window.SIDURON_SERVICES = {"ashkenaz":{"shacharit":[{"kind":"instruction","text":"מיד כשקם בבוקר יאמר מודה אני:","cond":[]},{"kind":"text","text":"מוֹדֶה (נשים אומרות: מוֹדָה) אֲנִי לְפָנֶיךָ, מֶלֶךְ חַי וְקַיָּם, שֶׁהֶחֱזַרְתָּ בִּי נִשְׁמָתִי בְּחֶמְלָה, רַבָּה אֱמוּנָתֶךָ.","cond":[]},{"kind":"instruction","text":"ייטול ידיו ויברך:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ עַל נְטִילַת יָדָיִם.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלַם, אֲשֶׁר יָצַר אֶת הָאָדָם בְּחָכְמָה, וּבָרָא בוֹ נְקָבִים נְקָבִים, חֲלוּלִים חֲלוּלִים. גָּלוּי וְיָדוּעַ לִפְנֵי כִסֵּא כְבוֹדֶךָ, שֶׁאִם יִפָּתֵחַ אֶחָד מֵהֶם אוֹ יִסָּתֵם אֶחָד מֵהֶם, אִי אֶפְשָׁר לְהִתְקַיֵּם וְלַעֲמֹד לְפָנֶיךָ. בָּרוּךְ אַתָּה יהוה, רוֹפֵא כָל בָּשָׂר וּמַפְלִיא לַעֲשׂוֹת.","cond":[]},{"kind":"instruction","text":"ישתדל להצמיד ברכת אלהי נשמה לברכת אשר יצר. אם שכח ישתדל לברך את ברכת אלהי נשמה בצמוד לברכה אחרת.","cond":[]},{"kind":"text","text":"אֱלֹהַי, נְשָׁמָה שֶׁנָּתַתָּ בִּי טְהוֹרָה הִיא. אַתָּה בְרָאתָהּ, אַתָּה יְצַרְתָּהּ, אַתָּה נְפַחְתָּהּ בִּי, וְאַתָּה מְשַׁמְּרָהּ בְּקִרְבִּי, וְאַתָּה עָתִיד לִטְּלָהּ מִמֶּנִּי, וּלְהַחֲזִירָהּ בִּי לֶעָתִיד לָבוֹא. כָּל זְמַן שֶׁהַנְּשָׁמָה בְקִרְבִּי, מוֹדֶה (נשים אומרות: מוֹדָה) אֲנִי לְפָנֶיךָ, יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, רִבּוֹן כָּל הַמַּעֲשִׂים, אֲדוֹן כָּל הַנְּשָׁמוֹת. בָּרוּךְ אַתָּה יהוה, הַמַּחֲזִיר נְשָׁמוֹת לִפְגָרִים מֵתִים.","cond":[]},{"kind":"instruction","text":"סדר לבישת ציצית\n\nלפני שלובש טלית קטן מברך מעומד (ואם יתעטף בזמן הקרוב בטלית גדול לא יברך):","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ עַל מִצְוַת צִיצִית.\n\nיְהִי רָצוֹן מִלְּפָנֶיךָ, יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁתְּהֵא חֲשׁוּבָה מִצְוַת צִיצִית לְפָנֶיךָ כְּאִלּוּ קִיַּמְתִּיהָ בְּכָל פְּרָטֶיהָ וְדִקְדּוּקֶיהָ וְכַוָּנוֹתֶיהָ, וְתַרְיַ\"ג מִצְוׂת הַתְּלוּיוֹת בָּהּ, אָמֵן סֶלָה.","cond":[]},{"kind":"header","text":"ברכות התורה","cond":[]},{"kind":"instruction","text":"ברכות התורה:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ לַעֲסֹק בְּדִבְרֵי תוֹרָה.","cond":[]},{"kind":"instruction","text":"אין עונים אמן, אלא ממשיכים מיד לברכת והערב נא, מפני שזו ברכה אחת (שו\"ע סי' מ\"ז סע' ו, ובמשנ\"ב ס\"ק י\"א-י\"ב).","cond":[]},{"kind":"text","text":"וְהַעֲרֶב נָא, יהוה אֱלֹהֵינוּ, אֶת דִּבְרֵי תוֹרָתְךָ בְּפִינוּ וּבְפִי עַמְּךָ בֵּית יִשְׂרָאֵל, וְנִהְיֶה אֲנַחְנוּ וְצֶאֱצָאֵינוּ וְצֶאֱצָאֵי עַמְּךָ בֵּית יִשְׂרָאֵל כֻּלָּנוּ יוֹדְעֵי שְׁמֶךָ וְלוֹמְדֵי תוֹרָתְךָ לִשְׁמָהּ. בָּרוּךְ אַתָּה יהוה, הַמְלַמֵּד תּוֹרָה לְעַמּוֹ יִשְׂרָאֵל.\n\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר בָּחַר בָּנוּ מִכָּל הָעַמִּים וְנָתַן לָנוּ אֶת תּוֹרָתוֹ. בָּרוּךְ אַתָּה יהוה, נוֹתֵן הַתּוֹרָה.\n\nיְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ:\nיָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ:\nיִשָּׂא יהוה פָּנָיו אֵלֶיךָ וְיָשֵׂם לְךָ שָׁלוֹם:\n\nאֵלּוּ דְבָרִים שֶׁאֵין לָהֶם שִׁעוּר: הַפֵּאָה וְהַבִּכּוּרִים וְהָרֵאָיוֹן וּגְמִילוּת חֲסָדִים וְתַלְמוּד תּוֹרָה.\n\nאֵלּוּ דְבָרִים שֶׁאָדָם אוֹכֵל פֵּרוֹתֵיהֶם בָּעוֹלָם הַזֶּה וְהַקֶּרֶן קַיֶּמֶת לוֹ לָעוֹלָם הַבָּא, וְאֵלּוּ הֵן: כִּבּוּד אָב וָאֵם, וּגְמִילוּת חֲסָדִים, וְהַשְׁכָּמַת בֵּית הַמִּדְרָשׁ שַׁחֲרִית וְעַרְבִית, וְהַכְנָסַת אוֹרְחִים, וּבִקּוּר חוֹלִים, וְהַכְנָסַת כַּלָּה, וּלְוָיַת הַמֵּת, וְעִיּוּן תְּפִלָּה, וַהֲבָאַת שָׁלוֹם בֵּין אָדָם לַחֲבֵרוֹ, וְתַלְמוּד תּוֹרָה כְּנֶגֶד כֻּלָּם.","cond":[]},{"kind":"header","text":"עטיפה בטלית","cond":["noTishaaBeav"]},{"kind":"instruction","text":"סדר לבישת טלית גדול\n\nיכוון בהתעטפו בטלית שציונו זאת הקב\"ה כדי לזכור כל מצוותיו לעשותם. לוקח הטלית ובודק ציציותיו אם הן כשרות, מפריד חוטיהן ואומר:","cond":["noTishaaBeav"]},{"kind":"text","text":"בָּרְכִי נַפְשִׁי אֶת יהוה, יהוה אֱלֹהַי גָּדַלְתָּ מְּאֹד, הוֹד וְהָדָר לָבָשְׁתָּ: עֹטֶה אוֹר כַּשַּׂלְמָה, נוֹטֶה שָׁמַיִם כַּיְרִיעָה:","cond":["noTishaaBeav"]},{"kind":"instruction","text":"יש אומרים:","cond":["noTishaaBeav"]},{"kind":"text","text":"לְשֵׁם יִחוּד קֻדְשָׁא בְּרִיךְ הוּא וּשְׁכִינְתֵּיהּ בִּדְחִילוּ וּרְחִימוּ, לְיַחֵד שֵׁם י\"ה בְּו\"ה בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל יִשְׂרָאֵל, הֲרֵינִי מִתְעַטֵּף בַּצִּיצִית, כֵּן תִּתְעַטֵּף נִשְׁמָתִי וּרְמַ\"ח אֵיבָרַי וּשְׁסָ\"ה גִידַי בְּאוֹר הַצִּיצִית הָעוֹלָה תַרְיַ\"ג. וּכְשֵׁם שֶׁאֲנִי מִתְכַּסֶּה בְּטַלִּית בָּעוֹלָם הַזֶּה, כַּךְ אֶזְכֶּה לַחֲלוּקָא דְרַבָּנָן, וּלְטַלִּית נָאָה לָעוֹלָם הַבָּא בְּגַן עֵדֶן. וְעַל יְדֵי מִצְוַת צִיצִית, תִּנָּצֵל נַפְשִׁי וְרוּחִי וְנִשְׁמָתִי וּתְפִלָּתִי מִן הַחִיצוֹנִים. וְהַטַּלִּית תִּפְרוֹשׂ כְּנָפֶיהָ עֲלֵיהֶם, וְתַצִּילֵם כְּנֶשֶׁר יָעִיר קִנּוֹ עַל גּוֹזָלָיו יְרַחֵף. וּתְהֵא חֲשׁוּבָה מִצְוַת צִיצִית לִפְנֵי הַקָּדוֹשׁ בָּרוּךְ הוּא כְּאִלּוּ קִיַּמְתִּיהָ בְּכָל פְּרָטֶיהָ וְדִקְדּוּקֶיהָ וְכַוָּנוֹתֶיהָ וְתַרְיַ\"ג מִצְוׂת הַתְּלוּיוֹת בָּהּ. אָמֵן סֶלָה.","cond":["noTishaaBeav"]},{"kind":"instruction","text":"אוחז את הטלית בשתי ידיו ויברך מעומד:","cond":["noTishaaBeav"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ לְהִתְעַטֵּף בַּצִּיצִית.","cond":["noTishaaBeav"]},{"kind":"instruction","text":"יתעטף בטלית ויכסה בה את ראשו ויישאר כך מעוטף איזה פרק זמן, ולאחר מכן יסיר העיטוף ויישאר לבוש בטלית.\n\nאחרי העטיפה יאמר:","cond":["noTishaaBeav"]},{"kind":"text","text":"מַה יָּקָר חַסְדְּךָ אֱלֹהִים, וּבְנֵי אָדָם בְּצֵל כְּנָפֶיךָ יֶחֱסָיוּן: יִרְוְיֻן מִדֶּשֶׁן בֵּיתֶךָ וְנַחַל עֲדָנֶיךָ תַשְׁקֵם: כִּי עִמְּךָ מְקוֹר חַיִּים, בְּאוֹרְךָ נִרְאֶה אוֹר: מְשֹׁךְ חַסְדְּךָ לְיֹדְעֶיךָ וְצִדְקָתְךָ לְיִשְׁרֵי לֵב:","cond":["noTishaaBeav"]},{"kind":"header","text":"הנחת תפילין","cond":["noTishaaBeav"]},{"kind":"instruction","text":"הנחת תפילין","cond":["noTishaaBeav"]},{"kind":"instruction","text":"פוסקי אשכנז פסקו שבחול המועד מניחים תפילין. למרות זאת, פשט המנהג בחלק מהקהילות שלא להניח. לכן, כל אחד יעשה כמנהגו. ויש פוסקים שכתבו שיניח ללא ברכה. מי שמתפלל בקהילה שבה לא מניחים תפילין גם הוא לא יניח בבית הכנסת אלא בביתו.","cond":["noTishaaBeav","pesach"]},{"kind":"instruction","text":"פוסקי אשכנז פסקו שבחול המועד מניחים תפילין. למרות זאת, פשט המנהג בחלק מהקהילות שלא להניח. לכן, כל אחד יעשה כמנהגו. ויש פוסקים שכתבו שיניח ללא ברכה. מי שמתפלל בקהילה שבה לא מניחים תפילין גם הוא לא יניח בבית הכנסת אלא בביתו.","cond":["noTishaaBeav","sucot"]},{"kind":"instruction","text":"יש אומרים:","cond":["noTishaaBeav"]},{"kind":"text","text":"לְשֵׁם יִחוּד קֻדְשָׁא בְּרִיךְ הוּא וּשְׁכִינְתֵּיהּ בִּדְחִילוּ וּרְחִימוּ, לְיַחֵד שֵׁם י\"ה בְּו\"ה בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל יִשְׂרָאֵל, הִנְנִי מְכַוֵּן בַּהֲנָחַת תְּפִלִּין לְקַיֵּם מִצְוַת בּוֹרְאִי, שֶׁצִּוָּנוּ לְהָנִיחַ תְּפִלִּין, כַּכָּתוּב בְּתוֹרָתוֹ: וּקְשַׁרְתָּם לְאוֹת עַל יָדֶךָ, וְהָיוּ לְטֹטָפֹת בֵּין עֵינֶיךָ: וְהֵם אַרְבַּע פַּרְשִׁיּוֹת אֵלּוּ: \"שְׁמַע\", \"וְהָיָה אִם שָׁמֹעַ\", \"קַדֶּשׁ לִי\", \"וְהָיָה כִּי יְבִיאֲךָ\", שֶׁיֵּשׁ בָּהֶם יִחוּדוֹ וְאַחְדוּתוֹ יִתְבָּרַךְ שְׁמוֹ בָּעוֹלָם, וְשֶׁנִּזְכֹּר נִסִּים וְנִפְלָאוֹת, שֶׁעָשָׂה עִמָּנוּ בְּהוֹצִיאוֹ אוֹתָנוּ מִמִּצְרָיִם, וַאֲשֶׁר לוֹ הַכֹּחַ וְהַמֶּמְשָׁלָה בָּעֶלְיוֹנִים וּבַתַּחְתּוֹנִים לַעֲשׂוֹת בָּהֶם כִּרְצוֹנוֹ. וְצִוָּנוּ לְהָנִיחַ עַל הַיָּד לְזִכְרוֹן זְרוֹעַ הַנְּטוּיָה, וְשֶׁהִיא נֶגֶד הַלֵּב לְשַׁעְבֵּד בָּזֶה תַּאֲווֹת וּמַחְשְׁבוֹת לִבֵּנוּ לַעֲבוֹדָתוֹ יִתְבָּרַךְ שְׁמוֹ, וְעַל הָרֹאשׁ נֶגֶד הַמֹּחַ, שֶׁהַנְּשָׁמָה שֶׁבְּמֹחִי עִם שְׁאָר חוּשַׁי וְכֹחוֹתַי כֻּלָּם יִהְיוּ מְשֻׁעְבָּדִים לַעֲבוֹדָתוֹ יִתְבָּרַךְ שְׁמוֹ. וּמִשֶּׁפַע מִצְוַת תְּפִלִּין יִתְמַשֵּׁךְ עָלַי לִהְיוֹת לִי חַיִּים אֲרֻכִּים וְשֶׁפַע קֹדֶשׁ וּמַחֲשָׁבוֹת קְדוֹשׁוֹת, בְּלִי הִרְהוּר חֵטְא וְעָוׂן כְּלָל, וְשֶׁלּא יְפַתֵּנוּ וְלֹא יִתְגָּרֶה בָּנוּ יֵצֶר הָרָע, וִינִיחֵנוּ לַעֲבֹד אֶת יהוה כַּאֲשֶׁר עִם לְבָבֵנוּ. וִיהִי רָצוֹן מִלְּפָנֶיךָ, יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתְּהֵא חֲשׁוּבָה מִצְוַת הֲנָחַת תְּפִלִּין לִפְנֵי הַקָּדושׁ בָּרוּךְ הוּא כְּאִלּוּ קִיַּמְתִּיהָ בְּכָל פְּרָטֶיהָ וְדִקְדּוּקֶיהָ וְכַוָּנוֹתֶיהָ וְתַרְיַ\"ג מִצְוׂת הַתְּלוּיוֹת בָּהּ, אָמֵן סֶלָה.","cond":["noTishaaBeav"]},{"kind":"instruction","text":"יש אומרים שמברכים רק ברכה אחת על התפילין, והיא ברכת \"להניח תפילין\", ואם שח בין של יד לשל ראש, מברך על של ראש \"על מצות תפילין\". אבל המנהג העיקרי באשכנז הוא לברך \"על מצות תפילין\" על של ראש בכל מקרה בלחש, ולומר לאחר מכן \"ברוך שם כבוד מלכותו לעולם ועד\" שמא היתה זו ברכה לבטלה. על פי שיטה זו, אם שח בין של יד לשל ראש, מברך על של ראש את שתי הברכות.\n\nיניח את התפילה של יד במקומה ולפני הקשירה יברך:","cond":["noTishaaBeav"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ לְהָנִיחַ תְּפִלִּין.","cond":["noTishaaBeav"]},{"kind":"instruction","text":"יהדק את הרצועה ויכרוך שבע כריכות סביב הזרוע, ולאחר מכן יניח התפילה של ראש במקומה, ולפני ההידוק יברך בלחש (ויש אומרים שלא יברך):","cond":["noTishaaBeav"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ עַל מִצְוַת תְּפִלִּין.","cond":["noTishaaBeav"]},{"kind":"instruction","text":"ומהדקו בראשו ואומר:","cond":["noTishaaBeav"]},{"kind":"text","text":"בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד:","cond":["noTishaaBeav"]},{"kind":"instruction","text":"יש אומרים:","cond":["noTishaaBeav"]},{"kind":"text","text":"וּמֵחָכְמָתְךָ אֵל עֶלְיוֹן תַּאֲצִיל עָלַי, וּמִבִּינָתְךָ תְּבִינֵנִי, וּבְחַסְדְּךָ תַּגְדִּיל עָלַי, וּבִגְבוּרָתְךָ תַּצְמִית אוֹיְבַי וְקָמַי. וְשֶׁמֶן הַטּוֹב תָּרִיק עַל שִׁבְעָה קְנֵי הַמְּנוֹרָה, לְהַשְׁפִּיעַ טוּבְךָ לִבְרִיּוֹתֶיךָ. פּוֹתֵחַ אֶת יָדֶךָ וּמַשְׂבִּיעַ לְכָל חַי רָצוֹן:","cond":["noTishaaBeav"]},{"kind":"instruction","text":"אחר כך יכרוך שלש כריכות סביב האצבע האמצעית ויכרוך בתחלה כריכה אחת בפרק האמצעי ואחר כך אחת בראש פרק התחתון ואחת בסוף פרק התחתון ואומר:","cond":["noTishaaBeav"]},{"kind":"text","text":"וְאֵרַשְׂתִּיךְ לִי לְעוֹלָם: וְאֵרַשְׂתִּיךְ לִי בְּצֶדֶק וּבְמִשְׁפָּט וּבְחֶסֶד וּבְרַחֲמִים: וְאֵרַשְׂתִּיךְ לִי בֶּאֱמוּנָה, וְיָדַעַתְּ אֶת יהוה:","cond":["noTishaaBeav"]},{"kind":"instruction","text":"אחר הנחת תפלין יאמר שתי פרשיות אלה:","cond":["noTishaaBeav"]},{"kind":"text","text":"וַיְדַבֵּר יהוה אֶל מֹשֶׁה לֵּאמֹר: קַדֶּשׁ לִי כָל בְּכוֹר פֶּטֶר כָּל רֶחֶם בִּבְנֵי יִשְׂרָאֵל בָּאָדָם וּבַבְּהֵמָה, לִי הוּא: וַיֹּאמֶר מֹשֶׁה אֶל הָעָם זָכוֹר אֶת הַיּוֹם הַזֶּה אֲשֶׁר יְצָאתֶם מִמִּצְרַיִם מִבֵּית עֲבָדִים, כִּי בְּחֹזֶק יָד הוֹצִיא יהוה אֶתְכֶם מִזֶּה, וְלֹא יֵאָכֵל חָמֵץ: הַיּוֹם אַתֶּם יֹצְאִים, בְּחֹדֶשׁ הָאָבִיב: וְהָיָה כִי יְבִיאֲךָ יהוה אֶל אֶרֶץ הַכְּנַעֲנִי וְהַחִתִּי וְהָאֱמֹרִי וְהַחִוִּי וְהַיְבוּסִי אֲשֶׁר נִשְׁבַּע לַאֲבֹתֶיךָ לָתֶת לָךְ, אֶרֶץ זָבַת חָלָב וּדְבָשׁ, וְעָבַדְתָּ אֶת הָעֲבֹדָה הַזֹּאת בַּחֹדֶשׁ הַזֶּה: שִׁבְעַת יָמִים תֹּאכַל מַצֹּת וּבַיּוֹם הַשְּׁבִיעִי חַג לַיהוה: מַצּוֹת יֵאָכֵל אֵת שִׁבְעַת הַיָּמִים, וְלֹא יֵרָאֶה לְךָ חָמֵץ וְלֹא יֵרָאֶה לְךָ שְׂאֹר בְּכָל גְּבֻלֶךָ: וְהִגַּדְתָּ לְבִנְךָ בַּיּוֹם הַהוּא לֵאמֹר, בַּעֲבוּר זֶה עָשָׂה יהוה לִי בְּצֵאתִי מִמִּצְרָיִם: וְהָיָה לְךָ לְאוֹת עַל יָדְךָ וּלְזִכָּרוֹן בֵּין עֵינֶיךָ, לְמַעַן תִּהְיֶה תּוֹרַת יהוה בְּפִיךָ, כִּי בְּיָד חֲזָקָה הוֹצִאֲךָ יהוה מִמִּצְרָיִם: וְשָׁמַרְתָּ אֶת הַחֻקָּה הַזֹּאת לְמוֹעֲדָהּ, מִיָּמִים יָמִימָה:\n\nוְהָיָה כִּי יְבִאֲךָ יהוה אֶל אֶרֶץ הַכְּנַעֲנִי כַּאֲשֶׁר נִשְׁבַּע לְךָ וְלַאֲבֹתֶיךָ, וּנְתָנָהּ לָךְ: וְהַעֲבַרְתָּ כָל פֶּטֶר רֶחֶם לַיהוה, וְכָל פֶּטֶר שֶׁגֶר בְּהֵמָה אֲשֶׁר יִהְיֶה לְךָ הַזְּכָרִים לַיהוה: וְכָל פֶּטֶר חֲמֹר תִּפְדֶּה בְשֶׂה, וְאִם לֹא תִפְדֶּה וַעֲרַפְתּוֹ, וְכֹל בְּכוֹר אָדָם בְּבָנֶיךָ תִּפְדֶּה: וְהָיָה כִּי יִשְׁאָלְךָ בִנְךָ מָחָר לֵּאמֹר מַה זֹּאת, וְאָמַרְתָּ אֵלָיו, בְּחֹזֶק יָד הוֹצִיאָנוּ יהוה מִמִּצְרַיִם מִבֵּית עֲבָדִים: וַיְהִי כִּי הִקְשָׁה פַרְעֹה לְשַׁלְּחֵנוּ, וַיַּהֲרֹג יהוה כָּל בְּכוֹר בְּאֶרֶץ מִצְרַיִם, מִבְּכֹר אָדָם וְעַד בְּכוֹר בְּהֵמָה, עַל כֵּן אֲנִי זֹבֵחַ לַיהוה כָּל פֶּטֶר רֶחֶם הַזְּכָרִים וְכָל בְּכוֹר בָּנַי אֶפְדֶּה: וְהָיָה לְאוֹת עַל יָדְכָה וּלְטוֹטָפֹת בֵּין עֵינֶיךָ, כִּי בְּחֹזֶק יָד הוֹצִיאָנוּ יהוה מִמִּצְרָיִם:","cond":["noTishaaBeav"]},{"kind":"header","text":"מה טובו","cond":[]},{"kind":"instruction","text":"כשנכנס לבית הכנסת יאמר זה:","cond":[]},{"kind":"text","text":"מַה טֹּבוּ אֹהֲלֶיךָ יַעֲקֹב, מִשְׁכְּנֹתֶיךָ יִשְׂרָאֵל: וַאֲנִי בְּרֹב חַסְדְּךָ אָבוֹא בֵיתֶךָ, אֶשְׁתַּחֲוֶה אֶל הֵיכַל קָדְשְׁךָ בְּיִרְאָתֶךָ: יהוה, אָהַבְתִּי מְעוֹן בֵּיתֶךָ וּמְקוֹם מִשְׁכַּן כְּבוֹדֶךָ: וַאֲנִי אֶשְׁתַּחֲוֶה וְאֶכְרָעָה, אֶבְרְכָה לִפְנֵי יהוה עֹשִׂי. וַאֲנִי תְפִלָּתִי לְךָ, יהוה, עֵת רָצוֹן, אֱלֹהִים בְּרֹב חַסְדֶּךָ, עֲנֵנִי בֶּאֱמֶת יִשְׁעֶךָ:","cond":[]},{"kind":"instruction","text":"פיוטים","cond":[]},{"kind":"text","text":"אֲדוֹן עוֹלָם אֲשֶׁר מָלַךְ, בְּטֶרֶם כָּל יְצִיר נִבְרָא. לְעֵת נַעֲשָׂה בְחֶפְצוֹ כֹּל, אֲזַי מֶלֶךְ שְׁמוֹ נִקְרָא. וְאַחֲרֵי כִּכְלוֹת הַכֹּל, לְבַדּוֹ יִמְלֹךְ נוֹרָא. וְהוּא הָיָה וְהוּא הֹוֶה, וְהוּא יִהְיֶה בְּתִפְאָרָה. וְהוּא אֶחָד וְאֵין שֵׁנִי, לְהַמְשִׁיל לוֹ לְהַחְבִּירָה. בְּלִי רֵאשִׁית בְּלִי תַכְלִית, וְלוֹ הָעֹז וְהַמִּשְׂרָה. וְהוּא אֵלִי וְחַי גוֹאֲלִי, וְצוּר חֶבְלִי בְּעֵת צָרָה. וְהוּא נִסִּי וּמָנוֹס לִי, מְנָת כּוֹסִי בְּיוֹם אֶקְרָא. בְּיָדוֹ אַפְקִיד רוּחִי, בְּעֵת אִישָׁן וְאָעִירָה. וְעִם רוּחִי גְּוִיָּתִי, יהוה לִי וְלֹא אִירָא.","cond":[]},{"kind":"text","text":"יִגְדַּל אֱלֹהִים חַי וְיִשְׁתַּבַּח, נִמְצָא וְאֵין עֵת אֶל מְצִיאוּתוֹ. אֶחָד וְאֵין יָחִיד כְּיִחוּדוֹ, נֶעְלָם וְגַם אֵין סוֹף לְאַחְדוּתוֹ. אֵין לוֹ דְּמוּת הַגּוּף וְאֵינוֹ גוּף, לֹא נַעֲרֹךְ אֵלָיו קְדֻשָּׁתוֹ. קַדְמוֹן לְכָל דָבָר אֲשֶׁר נִבְרָא, רִאשׁוֹן וְאֵין רֵאשִׁית לְרֵאשִׁיתוֹ. הִנּוֹ אֲדוֹן עוֹלָם לְכָל נוֹצָר, יוֹרֶה גְדֻלָּתוֹ וּמַלְכוּתוֹ. שֶׁפַע נְבוּאָתוֹ נְתָנוֹ, אֶל אַנְשֵׁי סְגֻלָּתוֹ וְתִפְאַרְתּוֹ. לֹא קָם בְּיִשְׂרָאֵל כְּמֹשֶׁה עוֹד, נָבִיא וּמַבִּיט אֶת תְּמוּנָתוֹ. תּוֹרַת אֱמֶת נָתַן לְעַמּוֹ אֵל, עַל יַד נְבִיאוֹ נֶאֱמַן בֵּיתוֹ. לֹא יַחֲלִיף הָאֵל וְלֹא יָמִיר דָתוֹ, לְעוֹלָמִים לְזוּלָתוֹ. צוֹפֶה וְיוֹדֵעַ סְתָרֵינוּ, מַבִּיט לְסוֹף דָבָר בְּקַדְמָתוֹ. גּוֹמֵל לְאִישׁ-חֶסֶד כְּמִפְעָלוֹ, נוֹתֵן לְרָשָׁע רָע כְּרִשְׁעָתוֹ. יִשְׁלַח לְקֵץ הַיָּמִין מְשִׁיחֵנוּ, לִפְדּוֹת מְחַכֵּי קֵץ יְשׁוּעָתוֹ. מֵתִים יְחַיֶּה אֵל בְּרֹב חַסְדּוֹ, בָּרוּךְ עֲדֵי-עַד שֵׁם תְּהִלָּתוֹ.","cond":[]},{"kind":"header","text":"ברכות השחר","cond":[]},{"kind":"instruction","text":"ברכות השחר","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר נָתַן לַשֶּׂכְוִי בִינָה לְהַבְחִין בֵּין יוֹם וּבֵין לָיְלָה.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁלֹּא עָשַׂנִי גּוֹי (לנקבה: גּוֹיָה).\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁלֹּא עָשַׂנִי עָבֶד (לנקבה: שִׁפְחָה).\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁלֹּא עָשַׂנִי אִשָּׁה (לנקבה: שֶׁעָשַׂנִי כִּרְצוֹנוֹ).\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, פּוֹקֵחַ עִוְרִים.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, מַלְבִּישׁ עֲרֻמִּים.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, מַתִּיר אֲסוּרִים.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, זוֹקֵף כְּפוּפִים.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, רוֹקַע הָאָרֶץ עַל הַמָּיִם.","cond":[]},{"kind":"instruction","text":"יש שאינם מברכים ברכת \"שעשה לי כל צרכי\" בתשעה באב. ויש אומרים שאפשר לברך אם מתכוון במוצאי הצום לנעול את נעליו הרגילות.","cond":["tishaaBeav"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁעָשָׂה לִּי כָּל צָרְכִּי.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַמֵּכִין מִצְעֲדֵי גָבֶר.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אוֹזֵר יִשְׂרָאֵל בִּגְבוּרָה.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, עוֹטֵר יִשְׂרָאֵל בְּתִפְאָרָה.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַנּוֹתֵן לַיָּעֵף כֹּחַ.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַמַּעֲבִיר שֵׁנָה מֵעֵינָי וּתְנוּמָה מֵעַפְעַפָּי. וִיהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתַּרְגִּילֵנוּ בְּתוֹרָתֶךָ, וְדַבְּקֵנוּ בְּמִצְוׂתֶיךָ, וְאַל תְּבִיאֵנוּ לֹא לִידֵי חֵטְא, וְלֹא לִידֵי עֲבֵרָה וְעָוׂן, וְלֹא לִידֵי נִסָּיוֹן, וְלֹא לִידֵי בִזָּיוֹן, וְאַל תַּשְׁלֶט בָּנוּ יֵצֶר הָרָע, וְהַרְחִיקֵנוּ מֵאָדָם רָע וּמֵחָבֵר רָע, וְדַבְּקֵנוּ בְּיֵצֶר הַטוֹב וּבְמַעֲשִׂים טוֹבִים, וְכֹף אֶת יִצְרֵנוּ לְהִשְׁתַּעְבֶּד לָךְ, וּתְנֵנוּ הַיּוֹם וּבְכָל יוֹם לְחֵן וּלְחֶסֶד וּלְרַחֲמִים בְּעֵינֶיךָ וּבְעֵינֵי כָל רוֹאֵינוּ, וְתִגְמְלֵנוּ חֲסָדִים טוֹבִים. בָּרוּךְ אַתָּה יהוה, הַגּוֹמֵל חֲסָדִים טוֹבִים לְעַמּו יִשְׂרָאֵל.\n\nיְהִי רָצוֹן מִלְּפָנֶיךָ, יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁתַּצִּילֵנִי הַיּוֹם וּבְכָל יוֹם מֵעַזֵּי פָנִים וּמֵעַזּוּת פָּנִים, מֵאָדָם רָע, וּמֵחָבֵר רָע, וּמִשָּׁכֵן רָע, וּמִפֶּגַע רָע, וּמִשָּׂטָן הַמַּשְׁחִית, מִדִּין קָשֶׁה וּמִבַּעַל דִּין קָשֶׁה, בֵּין שֶׁהוּא בֶן בְּרִית וּבֵין שֶׁאֵינוֹ בֶן בְּרִית.","cond":[]},{"kind":"header","text":"פרשת העקדה","cond":[]},{"kind":"instruction","text":"פרשת העקדה","cond":[]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, זָכְרֵנוּ בְּזִכְרוֹן טוֹב לְפָנֶיךָ, וּפָקְדֵנוּ בִּפְקוּדת יְשׁוּעָה וְרַחֲמִים מִשְּׁמֵי שְׁמֵי קֶדֶם, וּזְכָר לָנוּ יהוה אֱלֹהֵינוּ אַהֲבַת הַקַּדְמוֹנִים אַבְרָהָם יִצְחָק וְיִשְׂרָאֵל עֲבָדֶיךָ, אֶת הַבְּרִית וְאֶת הַחֶסֶד וְאֶת הַשְּׁבוּעָה שֶׁנִּשְׁבַּעְתָּ לְאַבְרָהָם אָבִינוּ בְּהַר הַמּוֹרִיָּה, וְאֶת הָעֲקֵדָה שֶׁעָקַד אֶת יִצְחָק בְּנוֹ עַל גַּבֵּי הַמִּזְבֵּחַ, כַּכָּתוּב בְּתוֹרָתָךְ:","cond":[]},{"kind":"text","text":"וַיְהִי אַחַר הַדְּבָרִים הָאֵלֶּה, וְהָאֱלֹהִים נִסָּה אֶת אַבְרָהָם, וַיֹּאמֶר אֵלָיו אַבְרָהָם, וַיֹּאמֶר הִנֵּנִי: וַיֹּאמֶר קַח נָא אֶת בִּנְךָ אֶת יְחִידְךָ אֲשֶׁר אָהַבְתָּ אֶת יִצְחָק, וְלֶךְ לְךָ אֶל אֶרֶץ הַמֹּרִיָּה, וְהַעֲלֵהוּ שָׁם לְעֹלָה עַל אַחַד הֶהָרִים אֲשֶׁר אֹמַר אֵלֶיךָ: וַיַּשְׁכֵּם אַבְרָהָם בַּבֹּקֶר וַיַּחֲבֹשׁ אֶת חֲמֹרוֹ, וַיִּקַּח אֶת שְׁנֵי נְעָרָיו אִתּוֹ וְאֵת יִצְחָק בְּנוֹ, וַיְבַקַּע עֲצֵי עֹלָה וַיָּקָם וַיֵּלֶךְ אֶל הַמָּקוֹם אֲשֶׁר אָמַר לוֹ הָאֱלֹהִים: בַּיּוֹם הַשְּׁלִישִׁי וַיִּשָּׂא אַבְרָהָם אֶת עֵינָיו, וַיַּרְא אֶת הַמָּקום מֵרָחוֹק: וַיֹּאמֶר אַבְרָהָם אֶל נְעָרָיו שְׁבוּ לָכֶם פֹּה עִם הַחֲמוֹר, וַאֲנִי וְהַנַּעַר נֵלְכָה עַד כֹּה, וְנִשְׁתַּחֲוֶה וְנָשׁוּבָה אֲלֵיכֶם: וַיִּקַּח אַבְרָהָם אֶת עֲצֵי הָעֹלָה וַיָּשֶׂם עַל יִצְחָק בְּנוֹ, וַיִּקַּח בְּיָדוֹ אֶת הָאֵשׁ וְאֶת הַמַּאֲכֶלֶת, וַיֵּלְכוּ שְׁנֵיהֶם יַחְדָּו: וַיֹּאמֶר יִצְחָק אֶל אַבְרָהָם אָבִיו וַיֹּאמֶר אָבִי, וַיֹּאמֶר הִנֶּנִּי בְנִי, וַיֹּאמֶר הִנֵּה הָאֵשׁ וְהָעֵצִים וְאַיֵּה הַשֶּׂה לְעֹלָה: וַיֹּאמֶר אַבְרָהָם: אֱלֹהִים יִרְאֶה לּוֹ הַשֶּׂה לְעֹלָה בְּנִי, וַיֵּלְכוּ שְׁנֵיהֶם יַחְדָּו: וַיָּבֹאוּ אֶל הַמָּקוֹם אֲשֶׁר אָמַר לוֹ הָאֱלֹהִים, וַיִּבֶן שָׁם אַבְרָהָם אֶת הַמִּזְבֵּחַ וַיַּעֲרֹךְ אֶת הָעֵצִים, וַיַּעֲקֹד אֶת יִצְחָק בְּנוֹ, וַיָּשֶׂם אֹתוֹ עַל הַמִּזְבֵּחַ מִמַּעַל לָעֵצִים: וַיִּשְׁלַח אַבְרָהָם אֶת יָדוֹ וַיִּקַּח אֶת הַמַּאֲכֶלֶת לִשְׁחֹט אֶת בְּנוֹ: וַיִּקְרָא אֵלָיו מַלְאַךְ יהוה מִן הַשָּׁמַיִם וַיֹּאמֶר אַבְרָהָם אַבְרָהָם, וַיֹּאמֶר הִנֵּנִי: וַיֹּאמֶר אַל תִּשְׁלַח יָדְךָ אֶל הַנַּעַר וְאַל תַּעַשׂ לוֹ מְאוּמָה, כִּי עַתָּה יָדַעְתִּי כִּי יְרֵא אֱלֹהִים אַתָּה וְלֹא חָשַׂכְתָּ אֶת בִּנְךָ אֶת יְחִידְךָ מִמֶּנִּי: וַיִּשָּׂא אַבְרָהָם אֶת עֵינָיו וַיַּרְא וְהִנֵּה אַיִל, אַחַר נֶאֱחַז בַּסְּבַךְ בְּקַרְנָיו, וַיֵּלֶךְ אַבְרָהָם וַיִּקַּח אֶת הָאַיִל, וַיַּעֲלֵהוּ לְעֹלָה תַּחַת בְּנוֹ: וַיִּקְרָא אַבְרָהָם שֵׁם הַמָּקוֹם הַהוּא יהוה יִרְאֶה, אֲשֶׁר יֵאָמֵר הַיּוֹם בְּהַר יהוה יֵרָאֶה: וַיִּקְרָא מַלְאַךְ יהוה אֶל אַבְרָהָם, שֵׁנִית מִן הַשָּׁמָיִם: וַיֹּאמֶר בִּי נִשְׁבַּעְתִּי נְאֻם יהוה, כִּי יַעַן אֲשֶׁר עָשִׂיתָ אֶת הַדָּבָר הַזֶּה וְלֹא חָשַׂכְתָּ אֶת בִּנְךָ אֶת יְחִידֶךָ: כִּי בָרֵךְ אֲבָרֶכְךָ וְהַרְבָּה אַרְבֶּה אֶת זַרְעֲךָ כְּכוֹכְבֵי הַשָּׁמַיִם וְכַחוֹל אֲשֶׁר עַל שְׂפַת הַיָּם, וְיִרַשׁ זַרְעֲךָ אֵת שַׁעַר אֹיְבָיו: וְהִתְבָּרְכוּ בְזַרְעֲךָ כֹּל גּוֹיֵי הָאָרֶץ, עֵקֶב אֲשֶׁר שָׁמַעְתָּ בְּקֹלִי: וַיָּשָׁב אַבְרָהָם אֶל נְעָרָיו וַיָּקֻמוּ וַיֵּלְכוּ יַחְדָּו אֶל בְּאֵר שָׁבַע, וַיֵּשֶׁב אַבְרָהָם בִּבְאֵר שָׁבַע:","cond":[]},{"kind":"text","text":"רִבּוֹנוֹ שֶׁל עוֹלָם, כְּמוֹ שֶׁכָּבַשׁ אַבְרָהָם אָבִינוּ אֶת רַחֲמָיו לַעֲשׂוֹת רְצוֹנְךָ בְּלֵבָב שָׁלֵם, כֵּן יִכְבְּשׁוּ רַחֲמֶיךָ אֶת כַּעַסְךָ מֵעָלֵינוּ וְיִגֹּלּוּ רַחֲמֶיךָ עַל מִדּוֹתֶיךָ. וְתִתְנַהֵג עִמָּנוּ יהוה אֱלֹהֵינוּ בְּמִדַּת הַחֶסֶד וּבְמִדַּת הָרַחֲמִים, וּבְטוּבְךָ הַגָּדוֹל יָשׁוּב חֲרוֹן אַפְּךָ מֵעַמְּךָ וּמֵעִירְךָ וּמֵאַרְצְךָ וּמִנַּחֲלָתֶךָ. וְקַיֶּם לָנוּ יהוה אֱלֹהֵינוּ אֶת הַדָּבָר שֶׁהִבְטַחְתָּנוּ בְּתוֹרָתֶךָ עַל יְדֵי משֶׁה עַבְדֶּךָ כָּאָמוּר: וְזָכַרְתִּי אֶת בְּרִיתִי יַעֲקוֹב, וְאַף אֶת בְּרִיתִי יִצְחָק, וְאַף אֶת בְּרִיתִי אַבְרָהָם אֶזְכֹּר וְהָאָרֶץ אֶזְכֹּר:","cond":[]},{"kind":"text","text":"לְעוֹלָם יְהֵא אָדָם יְרֵא שָׁמַיִם בְּסֵתֶר, וּמוֹדֶה עַל הָאֱמֶת, וְדוֹבֵר אֱמֶת בִּלְבָבוֹ, וְיַשְׁכֵּם וְיֹאמַר:\n\nרִבּוֹן כָּל הָעוֹלָמִים, לֹא עַל צִדְקוֹתֵינוּ אֲנַחְנוּ מַפִּילִים תַחֲנוּנֵינוּ לְפָנֶיךָ, כִּי עַל רַחֲמֶיךָ הָרַבִּים. מָה אֲנַחְנוּ, מֶה חַיֵּינוּ, מֶה חַסְדֵּנוּ, מַה צִּדְקָתֵנוּ, מַה יִּשְׁעֵנוּ, מַה כֹּחֵנוּ, מַה גְּבוּרָתֵנוּ, מַה נֹּאמַר לְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, הֲלֹא כָל הַגִּבּוֹרִים כְּאַיִן לְפָנֶיךָ וְאַנְשֵׁי הַשֵּׁם כְּלֹא הָיוּ וַחֲכָמִים כִּבְלִי מַדָּע וּנְבוֹנִים כִּבְלִי הַשְׂכֵּל, כִּי רֹב מַעֲשֵׂיהֶם תֹּהוּ וִימֵי חַיֵּיהֶם הֶבֶל לְפָנֶיךָ, וּמוֹתַר הָאָדָם מִן הַבְּהֵמָה אַיִן, כִּי הַכֹּל הָבֶל: אֲבָל אֲנַחְנוּ עַמְּךָ בְּנֵי בְרִיתֶךָ, בְּנֵי אַבְרָהָם אֹהַבְךָ שֶׁנִּשְׁבַּעְתָּ לּוֹ בְּהַר הַמּוֹרִיָּה, זֶרַע יִצְחָק יְחִידוֹ, שֶׁנֶּעֱקַד עַל גַּבֵּי הַמִּזְבֵּחַ, עֲדַת יַעֲקֹב בִּנְךָ בְּכוֹרֶךָ, שֶׁמֵּאַהֲבָתְךָ שֶׁאָהַבְתָּ אוֹתוֹ, וּמִשִּׂמְחָתְךָ שֶׁשָּׂמַחְתָּ בּוֹ, קָרָאתָ אֶת שְׁמוֹ יִשְׂרָאֵל וִישֻׁרוּן.\n\nלְפִיכָך אֲנַחְנוּ חַיָּבִים לְהוֹדוֹת לְךָ וּלְשַׁבֵּחֲךָ וּלְפָאֶרְךָ וּלְבָרֵך וּלְקַדֵּשׁ וְלָתֵת שֶׁבַח וְהוֹדָיָה לִשְׁמֶךָ. אַשְׁרֵינוּ, מַה טּוֹב חֶלְקֵנוּ וּמַה נָּעִים גּוֹרָלֵנוּ וּמַה יָּפָה יְרֻשָּׁתֵנוּ. אַשְׁרֵינוּ שֶׁאֲנַחְנוּ מַשְׁכִּימִים וּמַעֲרִיבִים עֶרֶב וָבֹקֶר וְאוֹמְרִים פַּעֲמַיִם בְּכָל יוֹם:","cond":[]},{"kind":"text","text":"שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:","cond":[]},{"kind":"instruction","text":"בלחש:","cond":[]},{"kind":"text","text":"בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד.\n\nוְאָהַבְתָּ אֵת יהוה אֱלֹהֶיךָ, בְּכָל לְבָבְךָ וּבְכָל נַפְשְׁךָ וּבְכָל מְאֹדֶךָ: וְהָיוּ הַדְּבָרִים הָאֵלֶּה אֲשֶׁר אָנֹכִי מְצַוְּךָ הַיּוֹם, עַל לְבָבֶךָ: וְשִׁנַּנְתָּם לְבָנֶיךָ וְדִבַּרְתָּ בָּם, בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ: וּקְשַׁרְתָּם לְאוֹת עַל יָדֶךָ, וְהָיוּ לְטֹטָפֹת בֵּין עֵינֶיךָ: וּכְתַבְתָּם עַל מְזֻזוֹת בֵּיתֶךָ וּבִשְׁעָרֶיךָ:","cond":[]},{"kind":"text","text":"אַתָּה הוּא עַד שֶׁלֹּא נִבְרָא הָעוֹלָם, אַתָּה הוּא מִשֶּׁנִּבְרָא הָעוֹלָם. אַתָּה הוּא בָּעוֹלָם הַזֶּה וְאַתָּה הוּא לָעוֹלָם הַבָּא. קַדֵּשׁ אֶת שִׁמְךָ עַל מַקְדִּישֵׁי שְׁמֶךָ וְקַדֵּשׁ אֶת שִׁמְךָ בְּעוֹלָמֶךָ, וּבִישׁוּעָתְךָ תָּרִים וְתַגְבִּיהַּ קַרְנֵנוּ. בָּרוּךְ אַתָּה יהוה, הַמְקַדֵּשׁ אֶת שְׁמוֹ בָּרַבִּים.\n\nאַתָּה הוּא יהוה אֱלֹהֵינוּ בַּשָּׁמַיִם וּבָאָרֶץ, וּבִשְׁמֵי הַשָּׁמַיִם הָעֶלְיוֹנִים. אֱמֶת, אַתָּה הוּא רִאשׁוֹן וְאַתָּה הוּא אַחֲרוֹן וּמִבַּלְעָדֶיךָ אֵין אֱלֹהִים. קַבֵּץ קֹוֶיךָ מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ. יַכִּירוּ וְיֵדְעוּ כָּל בָּאֵי עוֹלָם כִּי אַתָּה הוּא הָאֱלֹהִים לְבַדְּךָ לְכֹל מַמְלְכוֹת הָאָרֶץ, אַתָּה עָשִׂיתָ אֶת הַשָּׁמַיִם וְאֶת הָאָרֶץ, אֶת הַיָּם וְאֶת כָּל אֲשֶׁר בָּם, וּמִי בְּכָל מַעֲשֵׂי יָדֶיךָ בָּעֶלְיוֹנִים אוֹ בַתַּחְתּוֹנִים שֶׁיֹּאמַר לְךָ מַה תַּעֲשֶׂה. אָבִינוּ שֶׁבַּשָּׁמַיִם, עֲשֵׂה עִמָּנוּ חֶסֶד בַּעֲבוּר שִׁמְךָ הַגָּדוֹל שֶׁנִּקְרָא עָלֵינוּ, וְקַיֶּם לָנוּ יהוה אֱלֹהֵינוּ מַה שֶּׁכָּתוּב: בָּעֵת הַהִיא אָבִיא אֶתְכֶם, וּבָעֵת קַבְּצִי אֶתְכֶם, כִּי אֶתֵּן אֶתְכֶם לְשֵׁם וְלִתְהִלָּה בְּכֹל עַמֵּי הָאָרֶץ, בְּשׁוּבִי אֶת שְׁבוּתֵיכֶם לְעֵינֵיכֶם, אָמַר יהוה:","cond":[]},{"kind":"header","text":"סדר הקרבנות","cond":[]},{"kind":"instruction","text":"סדר הקרבנות","cond":[]},{"kind":"instruction","text":"פרשת הכיור","cond":[]},{"kind":"text","text":"וַיְדַבֵּר יהוה אֶל מֹשֶׁה לֵּאמֹר: וְעָשִׂיתָ כִּיּוֹר נְחֹשֶׁת וְכַנּוֹ נְחֹשֶׁת לְרָחְצָה, וְנָתַתָּ אֹתוֹ בֵּין אֹהֶל מוֹעֵד וּבֵין הַמִּזְבֵּחַ, וְנָתַתָּ שָׁמָּה מָיִם: וְרָחֲצוּ אַהֲרֹן וּבָנָיו מִמֶּנּוּ אֶת יְדֵיהֶם וְאֶת רַגְלֵיהֶם: בְּבֹאָם אֶל אֹהֶל מוֹעֵד יִרְחֲצוּ מַיִם וְלֹא יָמֻתוּ, אוֹ בְגִשְׁתָּם אֶל הַמִּזְבֵּחַ לְשָׁרֵת, לְהַקְטִיר אִשֶּׁה לַיהוה: וְרָחֲצוּ יְדֵיהֶם וְרַגְלֵיהֶם וְלֹא יָמֻתוּ, וְהָיְתָה לָהֶם חָק עוֹלָם, לוֹ וּלְזַרְעוֹ לְדֹרֹתָם:","cond":[]},{"kind":"instruction","text":"פרשת תרומת הדשן","cond":[]},{"kind":"text","text":"וַיְדַבֵּר יהוה אֶל מֹשֶׁה לֵּאמֹר: צַו אֶת אַהֲרֹן וְאֶת בָּנָיו לֵאמֹר, זֹאת תּוֹרַת הָעֹלָה, הִיא הָעֹלָה עַל מוֹקְדָה עַל הַמִּזְבֵּחַ כָּל הַלַּיְלָה עַד הַבֹּקֶר, וְאֵשׁ הַמִּזְבֵּחַ תּוּקַד בּוֹ: וְלָבַשׁ הַכֹּהֵן מִדּוֹ בַד וּמִכְנְסֵי בַד יִלְבַּשׁ עַל בְּשָׂרוֹ, וְהֵרִים אֶת הַדֶּשֶׁן אֲשֶׁר תֹּאכַל הָאֵשׁ, אֶת הָעֹלָה עַל הַמִּזְבֵּחַ, וְשָׂמוֹ אֵצֶל הַמִּזְבֵּחַ: וּפָשַׁט אֶת בְּגָדָיו, וְלָבַשׁ בְּגָדִים אֲחֵרִים, וְהוֹצִיא אֶת הַדֶּשֶׁן אֶל מִחוּץ לַמַּחֲנֶה אֶל מָקוֹם טָהור: וְהָאֵשׁ עַל הַמִּזְבֵּחַ תּוּקַד בּוֹ לֹא תִכְבֶּה, וּבִעֵר עָלֶיהָ הַכֹּהֵן עֵצִים בַּבֹּקֶר בַּבֹּקֶר, וְעָרַךְ עָלֶיהָ הָעֹלָה וְהִקְטִיר עָלֶיהָ חֶלְבֵי הַשְּׁלָמִים: אֵשׁ תָּמִיד תּוּקַד עַל הַמִּזְבֵּחַ לֹא תִכְבֶּה:","cond":[]},{"kind":"instruction","text":"פרשת התמיד","cond":[]},{"kind":"text","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתְּרַחֵם עָלֵינוּ וְתִמְחֹל לָנוּ עַל כָּל חַטֹּאתֵינוּ וּתְכַפֶּר לָנוּ עַל כָּל עֲוׂנוֹתֵינוּ וְתִסְלַח לָנוּ עַל כָּל פְּשָׁעֵינוּ, וְתִבְנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵינוּ, וְנַקְרִיב לְפָנֶיךָ קָרְבַּן הַתָּמִיד שֶׁיְּכַפֵּר בַּעֲדֵנוּ, כְּמוֹ שֶׁכָּתַבְתָּ עָלֵינוּ בְּתוֹרָתֶךָ עַל יְדֵי מֹשֶׁה עַבְדֶּךָ מִפִּי כְבוֹדֶךָ, כָּאָמוּר:\n\nוַיְדַבֵּר יהוה אֶל מֹשֶׁה לֵּאמֹר: צַו אֶת בְּנֵי יִשרָאֵל וְאָמַרְתָּ אֲלֵהֶם, אֶת קָרְבָּנִי לַחְמִי לְאִשַּׁי, רֵיחַ נִיחֹחִי, תִּשְׁמְרוּ לְהַקְרִיב לִי בְּמוֹעֲדוֹ: וְאָמַרְתָּ לָהֶם, זֶה הָאִשֶּׁה אֲשֶׁר תַּקְרִיבוּ לַיהוה, כְּבָשִׂים בְּנֵי שָׁנָה תְמִימִים, שְׁנַיִם לַיּוֹם עֹלָה תָמִיד: אֶת הַכֶּבֶשׂ אֶחָד תַּעֲשֶׂה בַבֹּקֶר, וְאֵת הַכֶּבֶשׂ הַשֵּׁנִי תַּעֲשֶׂה בֵּין הָעַרְבָּיִם: וַעֲשִׂירִית הָאֵיפָה סֹלֶת לְמִנְחָה, בְּלוּלָה בְּשֶׁמֶן כָּתִית רְבִיעִת הַהִין: עֹלַת תָּמִיד, הָעֲשֻׂיָה בְּהַר סִינַי, לְרֵיחַ נִיחֹחַ אִשֶּׁה לַיהוה: וְנִסְכּוֹ רְבִיעִת הַהִין לַכֶּבֶשׂ הָאֶחָד, בַּקֹּדֶשׁ הַסֵּךְ נֶסֶךְ שֵׁכָר לַיהוה: וְאֵת הַכֶּבֶשׂ הַשֵּׁנִי תַּעֲשֶׂה בֵּין הָעַרְבָּיִם, כְּמִנְחַת הַבֹּקֶר וּכְנִסְכּוֹ תַּעֲשֶׂה, אִשֵּׁה רֵיחַ נִיחֹחַ לַיהוה:\n\nוְשָׁחַט אֹתוֹ עַל יֶרֶךְ הַמִּזְבֵּחַ צָפֹנָה לִפְנֵי יהוה, וְזָרְקוּ בְּנֵי אַהֲרֹן הַכֹּהֲנִים אֶת דָּמוֹ עַל הַמִּזְבֵּחַ סָבִיב:\n\nיְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתְּהֵא אֲמִירָה זוֹ חֲשׁוּבָה וּמְקֻבֶּלֶת וּמְרֻצָּה לְפָנֶיךָ כְּאִלּוּ הִקְרַבְנוּ קָרְבַּן הַתָּמִיד בְּמוֹעֲדוֹ וּבִמְקוֹמוֹ וּכְהִלְכָתוֹ:","cond":[]},{"kind":"instruction","text":"פרשת הקטורת","cond":[]},{"kind":"text","text":"אַתָּה הוּא יהוה אֱלֹהֵינוּ שֶׁהִקְטִירוּ אֲבוֹתֵינוּ לְפָנֶיךָ אֶת קְטֹרֶת הַסַּמִּים בִּזְמַן שֶׁבֵּית הַמִּקְדָּשׁ הָיָה קַיָּם, כַּאֲשֶׁר צִוִּיתָ אוֹתָם עַל יַד מֹשֶׁה נְבִיאֶךָ, כַּכָּתוּב בְּתוֹרָתֶךָ: וַיֹּאמֶר יהוה אֶל מֹשֶׁה, קַח לְךָ סַמִּים נָטָף וּשְׁחֵלֶת וְחֶלְבְּנָה סַמִּים וּלְבֹנָה זַכָּה בַּד בְּבַד יִהְיֶה: וְעָשִׂיתָ אֹתָהּ קְטֹרֶת, רֹקַח מַעֲשֶׂה רוֹקֵחַ, מְמֻלָּח טָהוֹר קֹדֶשׁ: וְשָׁחַקְתָּ מִמֶּנָּה הָדֵק, וְנָתַתָּה מִמֶּנָּה לִפְנֵי הָעֵדֻת בְּאֹהֶל מוֹעֵד אֲשֶׁר אִוָּעֵד לְךָ שָׁמָּה, קֹדֶשׁ קָדָשִׁים תִּהְיֶה לָכֶם:\n\nוְנֶאֱמַר: וְהִקְטִיר עָלָיו אַהֲרֹן קְטֹרֶת סַמִּים, בַּבֹּקֶר בַּבֹּקֶר בְּהֵיטִיבוֹ אֶת הַנֵּרוֹת יַקְטִירֶנָּה: וּבְהַעֲלֹת אַהֲרֹן אֶת הַנֵּרֹת בֵּין הָעַרְבַּיִם יַקְטִירֶנָּה, קְטֹרֶת תָּמִיד לִפְנֵי יהוה לְדֹרֹתֵיכֶם:\n\nתָּנוּ רַבָּנָן: פִּטּוּם הַקְּטֹרֶת כֵּיצַד? שְׁלֹשׁ מֵאוֹת וְשִׁשִּׁים וּשְׁמוֹנָה מָנִים הָיוּ בָהּ. שְׁלֹשׁ מֵאוֹת וְשִׁשִּׁים וַחֲמִשָּׁה כְּמִנְיַן יְמוֹת הַחַמָּה, מָנֶה לְכָל יוֹם, פְּרַס בְּשַׁחֲרִית וּפְרַס בֵּין הָעַרְבָּיִם. וּשְׁלֹשָׁה מָנִים יְתֵרִים שֶׁמֵּהֶם מַכְנִיס כֹּהֵן גָּדוֹל מְלֹא חָפְנָיו בְּיוֹם הַכִּפּוּרִים, וּמַחֲזִירָן לְמַכְתֶּשֶׁת בְּעֶרֶב יוֹם הַכִּפּוּרִים, וְשׁוֹחֲקָן יָפֶה יָפֶה כְּדֵי שֶׁתְּהֵא דַקָּה מִן הַדַּקָּה. וְאַחַד עָשָׂר סַמָּנִים הָיוּ בָהּ, וְאֵלּוּ הֵן: (א) הַצֳּרִי (ב) וְהַצִּפֹּרֶן, (ג) הַחֶלְבְּנָה (ד) וְהַלְּבוֹנָה מִשְׁקַל שִׁבְעִים שִׁבְעִים מָנֶה, (ה) מֹר (ו) וּקְצִיעָה, (ז) שִׁבֹּלֶת נֵרְדְּ (ח) וְכַרְכֹּם מִשְׁקַל שִׁשָּׁה עָשָׂר שִׁשָּׁה עָשָׂר מָנֶה, (ט) הַקֹּשְׁטְ שְׁנֵים עָשָׂר, (י) קִלּוּפָה שְׁלֹשָׁה, (יא) קִנָּמוֹן תִּשְׁעָה, בֹּרִית כַּרְשִׁינָה תִּשְׁעָה קַבִּין, יֵין קַפְרִיסִין סְאִין תְּלָתָא וְקַבִּין תְּלָתָא, וְאִם לֹא מָצָא יֵין קַפְרִיסִין מֵבִיא חֲמַר חִוַּרְיָן עַתִּיק. מֶלַח סְדוֹמִית רֹבַע מַעֲלֶה עָשָׁן כָּל שֶׁהוּא. רַבִּי נָתָן הַבַּבְלִי אוֹמֵר: אַף כִּפַּת הַיַּרְדֵּן כָּל שֶׁהוּא. וְאִם נָתַן בָּהּ דְּבַשׁ פְּסָלָהּ, וְאִם חִסַּר אַחַת מִכָּל סַמָּנֶיהָ חַיָּב מִיתָה.\n\nרַבָּן שִׁמְעוֹן בֶּן גַּמְלִיאֵל אוֹמֵר: הַצֳּרִי אֵינוֹ אֶלָּא שְׂרָף הַנּוֹטֵף מֵעֲצֵי הַקְּטָף. בֹּרִית כַּרְשִׁינָה שֶׁשָּׁפִין בָּהּ אֶת הַצִּפֹּרֶן כְּדֵי שֶׁתְּהֵא נָאָה. יֵין קַפְרִיסִין שֶׁשּׁוֹרִין בּוֹ אֶת הַצִּפֹּרֶן כְּדֵי שֶׁתְּהֵא עַזָּה. וַהֲלֹא מֵי רַגְלַיִם יָפִין לָהּ, אֶלָּא שֶׁאֵין מַכְנִיסִין מֵי רַגְלַיִם בַּמִּקְדָּשׁ מִפְּנֵי הַכָּבוֹד.\n\nתַּנְיָא: רַבִּי נָתָן אוֹמֵר: כְּשֶׁהוּא שׁוֹחֵק אוֹמֵר: הָדֵק הֵיטֵב, הֵיטֵב הָדֵק, מִפְּנֵי שֶׁהַקּוֹל יָפֶה לַבְּשָׂמִים. פִּטְּמָהּ לַחֲצָאִין כְּשֵׁרָה. לִשְׁלִישׁ וְלִרְבִיעַ לֹא שָׁמַעְנוּ. אָמַר רַבִּי יְהוּדָה: זֶה הַכְּלָל: אִם כְּמִדָּתָהּ כְּשֵׁרָה לַחֲצָאִין, וְאִם חִסַּר אַחַת מִכָּל סַמָּנֶיהָ חַיָּב מִיתָה.\n\nתַּנְיָא: בַּר קַפָּרָא אוֹמֵר: אַחַת לְשִׁשִּׁים אוֹ לְשִׁבְעִים שָׁנָה הָיְתָה בָאָה שֶׁל שִׁירַיִם לַחֲצָאִין. וְעוֹד תָּנֵי בַּר קַפָּרָא: אִלּוּ הָיָה נוֹתֵן בָּהּ קוֹרְטוֹב שֶׁל דְּבַשׁ אֵין אָדָם יָכוֹל לַעֲמֹד מִפְּנֵי רֵיחָהּ, וְלָמָה אֵין מְעָרְבִין בָּהּ דְּבַשׁ? מִפְּנֵי שֶׁהַתּוֹרָה אָמְרָה: כִּי כָל שְׂאֹר וְכָל דְּבַשׁ לֹא תַקְטִירוּ מִמֶּנּוּ אִשֶּׁה לַיהוה:\n\nיהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה:\nיהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה:\nיהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה:\n\nיהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ:\nיהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ:\nיהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ:\n\nיהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:\nיהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:\nיהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:\n\nאַתָּה סֵתֶר לִי מִצַּר תִּצְּרֵנִי רָנֵּי פַלֵּט תְּסוֹבְבֵנִי סֶלָה: וְעָרְבָה לַיהוה מִנְחַת יְהוּדָה וִירוּשָׁלָיִם כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמוֹנִיּות:","cond":[]},{"kind":"instruction","text":"סדר המערכה","cond":[]},{"kind":"text","text":"אַבַּיֵּי הֲוָה מְסַדֵּר סֵדֶר הַמַּעֲרָכָה מִשְּׁמָא דִּגְמָרָא וְאַלִּבָּא דְאַבָּא שָׁאוּל: מַעֲרָכָה גְדוֹלָה קוֹדֶמֶת לְמַעֲרָכָה שְׁנִיָּה שֶׁל קְטֹרֶת, וּמַעֲרָכָה שְׁנִיָּה שֶׁל קְטֹרֶת קוֹדֶמֶת לְסִדּוּר שְׁנֵי גִזְרֵי עֵצִים, וְסִדּוּר שְׁנֵי גִזְרֵי עֵצִים קוֹדֵם לְדִשּׁוּן מִזְבֵּחַ הַפְּנִימִי, וְדִשּׁוּן מִזְבֵּחַ הַפְּנִימִי קוֹדֵם לַהֲטָבַת חָמֵשׁ נֵרוֹת, וַהֲטָבַת חָמֵשׁ נֵרוֹת קוֹדֶמֶת לְדַם הַתָּמִיד, וְדַם הַתָּמִיד קוֹדֵם לַהֲטָבַת שְׁתֵּי נֵרוֹת, וַהֲטָבַת שְׁתֵּי נֵרוֹת קוֹדֶמֶת לִקְטֹרֶת, וּקְטֹרֶת קוֹדֶמֶת לְאֵבָרִים, וְאֵבָרִים לְמִנְחָה, וּמִנְחָה לַחֲבִתִּין, וַחֲבִתִּין לִנְסָכִין, וּנְסָכִין לְמוּסָפִין, וּמוּסָפִין לְבָזִיכִין, וּבָזִיכִין קוֹדְמִין לְתָמִיד שֶׁל בֵּין הָעַרְבָּיִם, שֶׁנֶּאֱמַר: וְעָרַךְ עָלֶיהָ הָעֹלָה, וְהִקְטִיר עָלֶיהָ חֶלְבֵי הַשְּׁלָמִים: עָלֶיהָ הַשְׁלֵם כָּל הַקָּרְבָּנות כֻּלָּם.","cond":[]},{"kind":"text","text":"אָנָּא, בְּכֹחַ גְּדֻלַּת יְמִינְךָ, תַּתִּיר צְרוּרָה (אב\"ג ית\"ץ).","cond":[]},{"kind":"text","text":"קַבֵּל רִנַּת עַמְּךָ, שַׂגְּבֵנוּ, טַהֲרֵנוּ, נוֹרָא (קר\"ע שט\"ן).","cond":[]},{"kind":"text","text":"נָא גִּבּוֹר, דּוֹרְשֵׁי יִחוּדֶךָ, כְּבָבַת שָׁמְרֵם (נג\"ד יכ\"ש).","cond":[]},{"kind":"text","text":"בָּרְכֵם, טַהֲרֵם, רַחֲמֵי צִדְקָתְךָ תָּמִיד גָּמְלֵם (בט\"ר צת\"ג).","cond":[]},{"kind":"text","text":"חָסִין קָדוֹשׁ, בְּרֹב טוּבְךָ נַהֵל עֲדָתֶךָ (חק\"ב טנ\"ע).","cond":[]},{"kind":"text","text":"יָחִיד גֵּאֶה, לְעַמְּךָ פְנֵה, זוֹכְרֵי קְדֻשָּׁתֶךָ (יג\"ל פז\"ק).","cond":[]},{"kind":"text","text":"שַׁוְעָתֵנוּ קַבֵּל, וּשְׁמַע צַעֲקָתֵנוּ, יוֹדֵעַ תַּעֲלוּמוֹת (שק\"ו צי\"ת).","cond":[]},{"kind":"text","text":"בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֵד.\n\nרִבּוֹן הָעוֹלָמִים, אַתָּה צִוִּיתָנוּ לְהַקְרִיב קָרְבַּן הַתָּמִיד בְּמוֹעֲדוֹ וְלִהְיוֹת כֹּהֲנִים בַּעֲבוֹדָתָם וּלְוִיִּם בְּדוּכָנָם וְיִשְׂרָאֵל בְּמַעֲמָדָם, וְעַתָּה בַּעֲוׂנוֹתֵינוּ חָרַב בֵּית הַמִּקְדָּשׁ וּבָטַל הַתָּמִיד וְאֵין לָנוּ לֹא כֹהֵן בַּעֲבוֹדָתוֹ וְלֹא לֵוִי בְּדוּכָנוֹ וְלֹא יִשְׂרָאֵל בְּמַעֲמָדוֹ, לָכֵן יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁיְּהֵא שִׂיחַ שִׂפְתוֹתֵינוּ חָשׁוּב וּמְקֻבָּל וּמְרֻצֶּה לְפָנֶיךָ כְּאִלּוּ הִקְרַבְנוּ קָרְבַּן הַתָּמִיד בְּמוֹעֲדוֹ וְעָמַדְנוּ עַל מַעֲמָדוֹ.","cond":[]},{"kind":"instruction","text":"פסוקי מוסף ראש חדש","cond":["rh"]},{"kind":"text","text":"וּבְרָאשֵׁי חָדְשֵׁיכֶם תַּקְרִיבוּ עֹלָה לַיהוה, פָּרִים בְּנֵי בָקָר שְׁנַיִם וְאַיִל אֶחָד, כְּבָשִׂים בְּנֵי שָׁנָה שִׁבְעָה, תְּמִימִם: וּשְׁלֹשָׁה עֶשְׂרֹנִים, סֹלֶת מִנְחָה בְּלוּלָה בַשֶּׁמֶן לַפָּר הָאֶחָד, וּשְׁנֵי עֶשְׂרֹנִים סֹלֶת מִנְחָה בְּלוּלָה בַשֶּׁמֶן לָאַיִל הָאֶחָד: וְעִשָּׂרֹן עִשָּׂרוֹן, סֹלֶת מִנְחָה בְּלוּלָה בַשֶּׁמֶן לַכֶּבֶשׂ הָאֶחָד, עֹלָה רֵיחַ נִיחֹחַ אִשֶּׁה לַיהוה: וְנִסְכֵּיהֶם חֲצִי הַהִין יִהְיֶה לַפָּר, וּשְׁלִישִׁת הַהִין לָאַיִל, וּרְבִיעִת הַהִין לַכֶּבֶשׂ יָיִן, זֹאת עֹלַת חֹדֶשׁ בְּחָדְשׁוֹ לְחָדְשֵׁי הַשָּׁנָה: וּשְׂעִיר עִזִּים אֶחָד לְחַטָּאת לַיהוה, עַל עֹלַת הַתָּמִיד יֵעָשֶׂה וְנִסְכּוֹ:","cond":["rh"]},{"kind":"header","text":"איזהו מקומן","cond":[]},{"kind":"instruction","text":"פרק איזהו מקומן","cond":[]},{"kind":"text","text":"אֵיזֶהוּ מְקוֹמָן שֶׁל זְבָחִים: קָדְשֵׁי קָדָשִׁים שְׁחִיטָתָן בַּצָּפוֹן. פָּר וְשָׂעִיר שֶׁל יוֹם הַכִּפּוּרִים שְׁחִיטָתָן בַּצָּפוֹן, וְקִבּוּל דָּמָן בִּכְלִי שָׁרֵת בַּצָּפוֹן, וְדָמָן טָעוּן הַזָּיָה עַל בֵּין הַבַּדִּים וְעַל הַפָּרֹכֶת וְעַל מִזְבַּח הַזָּהָב, מַתָּנָה אַחַת מֵהֶן מְעַכָּבֶת. שְׁיָרֵי הַדָּם הָיָה שׁוֹפֵךְ עַל יְסוֹד מַעֲרָבִי שֶׁל מִזְבֵּחַ הַחִיצוֹן, אִם לֹא נָתַן לֹא עִכֵּב.\n\nפָּרִים הַנִּשְׂרָפִים וּשְׂעִירִים הַנִּשְׂרָפִים שְׁחִיטָתָן בַּצָּפוֹן, וְקִבּוּל דָּמָן בִּכְלִי שָׁרֵת בַּצָּפוֹן, וְדָמָן טָעוּן הַזָּיָה עַל הַפָּרֹכֶת וְעַל מִזְבַּח הַזָּהָב, מַתָּנָה אַחַת מֵהֶן מְעַכָּבֶת. שְׁיָרֵי הַדָּם הָיָה שׁוֹפֵךְ עַל יְסוֹד מַעֲרָבִי שֶׁל מִזְבֵּחַ הַחִיצוֹן, אִם לֹא נָתַן לֹא עִכֵּב. אֵלּוּ וָאֵלּוּ נִשְׂרָפִין בְּבֵית הַדָּשֶׁן.\n\nחַטֹּאת הַצִּבּוּר וְהַיָּחִיד, אֵלּוּ הֵן חַטֹּאת הַצִּבּוּר: שְׂעִירֵי רָאשֵׁי חֳדָשִׁים וְשֶׁל מוֹעֲדוֹת, שְׁחִיטָתָן בַּצָּפוֹן, וְקִבּוּל דָּמָן בִּכְלִי שָׁרֵת בַּצָּפוֹן, וְדָמָן טָעוּן אַרְבַּע מַתָּנוֹת עַל אַרְבַּע קְרָנוֹת. כֵּיצַד? עָלָה בַכֶּבֶשׁ, וּפָנָה לַסּוֹבֵב, וּבָא לוֹ לְקֶרֶן דְּרוֹמִית מִזְרָחִית, מִזְרָחִית צְפוֹנִית, צְפוֹנִית מַעֲרָבִית, מַעֲרָבִית דְּרוֹמִית. שְׁיָרֵי הַדָּם הָיָה שׁוֹפֵךְ עַל יְסוֹד דְּרוֹמִי, וְנֶאֱכָלִין לִפְנִים מִן הַקְּלָעִים, לְזִכְרֵי כְהֻנָּה, בְּכָל מַאֲכָל, לְיוֹם וָלַיְלָה עַד חֲצוֹת.\n\nהָעוֹלָה קֹדֶשׁ קָדָשִׁים, שְׁחִיטָתָהּ בַּצָּפוֹן, וְקִבּוּל דָּמָהּ בִּכְלִי שָׁרֵת בַּצָּפוֹן, וְדָמָהּ טָעוּן שְׁתֵּי מַתָּנוֹת שֶׁהֵן אַרְבַּע, וּטְעוּנָה הֶפְשֵׁט וְנִתּוּחַ וְכָלִיל לָאִשִּׁים.\n\nזִבְחֵי שַׁלְמֵי צִבּוּר וַאֲשָׁמוֹת, אֵלּוּ הֵן אֲשָׁמוֹת: אֲשַׁם גְּזֵלוֹת, אֲשַׁם מְעִילוֹת, אֲשַׁם שִׁפְחָה חֲרוּפָה, אֲשַׁם נָזִיר, אֲשַׁם מְצֹרָע, אָשָׁם תָּלוּי, שְׁחִיטָתָן בַּצָּפוֹן, וְקִבּוּל דָּמָן בִּכְלִי שָׁרֵת בַּצָּפוֹן, וְדָמָן טָעוּן שְׁתֵּי מַתָּנוֹת שֶׁהֵן אַרְבַּע, וְנֶאֱכָלִין לִפְנִים מִן הַקְּלָעִים, לְזִכְרֵי כְהֻנָּה, בְּכָל מַאֲכָל, לְיוֹם וָלַיְלָה עַד חֲצוֹת.\n\nהַתּוֹדָה וְאֵיל נָזִיר קָדָשִׁים קַלִּים, שְׁחִיטָתָן בְּכָל מָקוֹם בָּעֲזָרָה, וְדָמָן טָעוּן שְׁתֵּי מַתָּנוֹת שֶׁהֵן אַרְבַּע, וְנֶאֱכָלִין בְּכָל הָעִיר, לְכָל אָדָם, בְּכָל מַאֲכָל, לְיוֹם וָלַיְלָה עַד חֲצוֹת. הַמּוּרָם מֵהֶם כַּיּוֹצֵא בָהֶם, אֶלָּא שֶׁהַמּוּרָם נֶאֱכָל לַכֹּהֲנִים לִנְשֵׁיהֶם וְלִבְנֵיהֶם וּלְעַבְדֵיהֶם.\n\nשְׁלָמִים קָדָשִׁים קַלִּים, שְׁחִיטָתָן בְּכָל מָקום בָּעֲזָרָה, וְדָמָן טָעוּן שְׁתֵּי מַתָּנוֹת שֶׁהֵן אַרְבַּע, וְנֶאֱכָלִין בְּכָל הָעִיר, לְכָל אָדָם, בְּכָל מַאֲכָל, לִשְׁנֵי יָמִים וְלַיְלָה אֶחָד. הַמּוּרָם מֵהֶם כַּיּוֹצֵא בָהֶם, אֶלָּא שֶׁהַמּוּרָם נֶאֱכָל לַכֹּהֲנִים לִנְשֵׁיהֶם וְלִבְנֵיהֶם וּלְעַבְדֵיהֶם.\n\nהַבְּכוֹר וְהַמַּעֲשֵׂר וְהַפֶּסַח קָדָשִׁים קַלִּים, שְׁחִיטָתָן בְּכָל מָקוֹם בָּעֲזָרָה, וְדָמָן טָעוּן מַתָּנָה אֶחָת, וּבִלְבָד שֶׁיִּתֵּן כְּנֶגֶד הַיְסוֹד. שִׁנָּה בַאֲכִילָתָן: הַבְּכוֹר נֶאֱכָל לַכֹּהֲנִים, וְהַמַּעֲשֵׂר לְכָל אָדָם. וְנֶאֱכָלִין בְּכָל הָעִיר, בְּכָל מַאֲכָל, לִשְׁנֵי יָמִים וְלַיְלָה אֶחָד. הַפֶּסַח אֵינוֹ נֶאֱכָל אֶלָּא בַלַּיְלָה, וְאֵינוֹ נֶאֱכָל אֶלָּא עַד חֲצוֹת, וְאֵינוֹ נֶאֱכָל אֶלָּא לִמְנוּיָיו, וְאֵינוֹ נֶאֱכָל אֶלָּא צָלִי.","cond":[]},{"kind":"header","text":"ברייתא דרבי ישמעאל","cond":[]},{"kind":"instruction","text":"ברייתא דרבי ישמעאל","cond":[]},{"kind":"text","text":"רַבִּי יִשְׁמָעֵאל אוֹמֵר: בִּשְׁלֹשׁ עֶשְׂרֵה מִדּוֹת הַתּוֹרָה נִדְרֶשֶׁת: מִקַּל וָחֹמֶר, וּמִגְּזֵרָה שָׁוָה, מִבִּנְיַן אָב מִכָּתוּב אֶחָד וּמִבִּנְיַן אָב מִשְּׁנֵי כְתוּבִים, מִכְּלָל וּפְרָט, וּמִפְּרָט וּכְלָל, כְּלָל וּפְרָט וּכְלָל אִי אַתָּה דָן אֶלָּא כְּעֵין הַפְּרָט, מִכְּלָל שֶׁהוּא צָרִיךְ לִפְרָט, וּמִפְּרָט שֶׁהוּא צָרִיךְ לִכְלָל, כָּל דָּבָר שֶׁהָיָה בִּכְלָל וְיָצָא מִן הַכְּלָל לְלַמֵּד לֹא לְלַמֵּד עַל עַצְמוֹ יָצָא אֶלָּא לְלַמֵּד עַל הַכְּלָל כֻּלּוֹ יָצָא, כָּל דָּבָר שֶׁהָיָה בִּכְלָל וְיָצָא לִטְעוֹן טֹעַן אֶחָד שֶׁהוּא כְעִנְיָנוֹ יָצָא לְהָקֵל וְלֹא לְהַחֲמִיר, כָּל דָּבָר שֶׁהָיָה בִּכְלָל וְיָצָא לִטְעוֹן טֹעַן אַחֵר שֶׁלֹּא כְעִנְיָנוֹ יָצָא לְהָקֵל וּלְהַחֲמִיר, כָּל דָּבָר שֶׁהָיָה בִּכְלָל וְיָצָא לִדּוֹן בְּדָבָר הֶחָדָשׁ אִי אַתָּה יָכוֹל לְהַחֲזִירוֹ לִכְלָלוֹ עַד שֶׁיַּחֲזִירֶנּוּ הַכָּתוּב לִכְלָלוֹ בְּפֵרוּשׁ, דָּבָר הַלָּמֵד מֵעִנְיָנוֹ וְדָבָר הַלָּמֵד מִסּוֹפוֹ, וְכֵן שְׁנֵי כְתוּבִים הַמַּכְחִישִׁים זֶה אֶת זֶה עַד שֶׁיָּבוֹא הַכָּתוּב הַשְּׁלִישִׁי וְיַכְרִיעַ בֵּינֵיהֶם.\n\nיְהִי רָצוֹן מִלְּפָנֶיךָ, יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁיִּבָּנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵינוּ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתֶךָ, וְשָׁם נַעֲבָדְךָ בְּיִרְאָה כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמוֹנִיּוֹת.","cond":[]},{"kind":"instruction","text":"קדיש דרבנן","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":[]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"עַל יִשְׂרָאֵל וְעַל רַבָּנָן וְעַל תַּלְמִידֵיהוֹן וְעַל כָּל תַּלְמִידֵי תַלְמִידֵיהוֹן, וְעַל כָּל מָאן דְּעָסְקִין בְּאוֹרַיְתָא, דִּי בְאַתְרָא (קַדִּישָׁא) הָדֵין וְדִי בְכָל אֲתָר וַאֲתָר, יְהֵא לְהוֹן וּלְכוֹן שְׁלָמָא רַבָּא, חִנָּא וְחִסְדָּא, וְרַחֲמֵי וְחַיֵּי אֲרִיכֵי וּמְזוֹנֵי רְוִיחֵי וּפֻרְקָנָא מִן קֳדָם אֲבוּהוֹן דִּי בִשְׁמַיָּא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"header","text":"פסוקי דזמרה","cond":[]},{"kind":"instruction","text":"פסוקי דזמרה","cond":[]},{"kind":"text","text":"מִזְמוֹר שִׁיר חֲנֻכַּת הַבַּיִת לְדָוִד: אֲרוֹמִמְךָ יהוה כִּי דִלִּיתָנִי, וְלֹא שִׂמַּחְתָּ אֹיְבַי לִי: יהוה אֱלֹהָי שִׁוַּעְתִּי אֵלֶיךָ וַתִּרְפָּאֵנִי: יהוה, הֶעֱלִיתָ מִן שְׁאוֹל נַפְשִׁי, חִיִּיתַנִי מִיָּרְדִי בוֹר: זַמְּרוּ לַיהוה חֲסִידָיו וְהוֹדוּ לְזֵכֶר קָדְשׁוֹ: כִּי רֶגַע בְּאַפּוֹ חַיִּים בִּרְצוֹנוֹ, בָּעֶרֶב יָלִין בֶּכִי וְלַבֹּקֶר רִנָּה: וַאֲנִי אָמַרְתִּי בְשַׁלְוִי בַּל אֶמּוֹט לְעוֹלָם: יהוה בִּרְצוֹנְךָ הֶעֱמַדְתָּה לְהַרְרִי עֹז, הִסְתַּרְתָּ פָנֶיךָ הָיִיתִי נִבְהָל: אֵלֶיךָ יהוה אֶקְרָא וְאֶל אֲדֹנָי אֶתְחַנָּן: מַה בֶּצַע בְּדָמִי בְּרִדְתִּי אֶל שָׁחַת, הֲיוֹדְךָ עָפָר הֲיַגִּיד אֲמִתֶּךָ: שְׁמַע יהוה וְחָנֵּנִי, יהוה הֱיֵה עֹזֵר לִי: הָפַכְתָּ מִסְפְּדִי לְמָחוֹל לִי, פִּתַּחְתָּ שַׂקִּי וַתְּאַזְּרֵנִי שִׂמְחָה: לְמַעַן יְזַמֶּרְךָ כָבוֹד וְלֹא יִדֹּם, יהוה אֱלֹהַי לְעוֹלָם אוֹדֶךָּ:","cond":[]},{"kind":"instruction","text":"קדיש יתום","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":[]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"הֲרֵינִי מְזַמֵּן אֶת פִּי לְהוֹדוֹת וּלְהַלֵּל וּלְשַׁבֵּחַ אֶת בּוֹרְאִי.","cond":[]},{"kind":"instruction","text":"אין להפסיק בדיבור מברוך שאמר ועד אחרי תפילת העמידה.\n\nברוך שאמר","cond":[]},{"kind":"text","text":"בָּרוּךְ שֶׁאָמַר וְהָיָה הָעוֹלָם, בָּרוּךְ הוּא, בָּרוּךְ עוֹשֶׂה בְרֵאשִׁית, בָּרוּךְ אוֹמֵר וְעוֹשֶׂה, בָּרוּךְ גּוֹזֵר וּמְקַיֵּם, בָּרוּךְ מְרַחֵם עַל הָאָרֶץ, בָּרוּךְ מְרַחֵם עַל הַבְּרִיּוֹת, בָּרוּךְ מְשַׁלֵּם שָׂכָר טוֹב לִירֵאָיו, בָּרוּךְ חַי לָעַד וְקַיָּם לָנֶצַח, בָּרוּךְ פּוֹדֶה וּמַצִּיל, בָּרוּךְ שְׁמוֹ.\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הָאֵל הָאָב הָרַחֲמָן הַמְהֻלָּל בְּפִי עַמּוֹ, מְשֻׁבָּח וּמְפֹאָר בִּלְשׁוֹן חֲסִידָיו וַעֲבָדָיו, וּבְשִׁירֵי דָוִד עַבְדֶּךָ, נְהַלֶּלְךָ יהוה אֱלֹהֵינוּ בִּשְׁבָחוֹת וּבִזְמִירוֹת, נְגַדֶּלְךָ וּנְשַׁבֵּחֲךָ וּנְפָאֶרְךָ וְנַזְכִּיר שִׁמְךָ וְנַמְלִיכְךָ מַלְכֵּנוּ אֱלֹהֵינוּ, יָחִיד חֵי הָעוֹלָמִים, מֶלֶךְ מְשֻׁבָּח וּמְפֹאָר עֲדֵי עַד שְׁמוֹ הַגָּדוֹל. בָּרוּךְ אַתָּה יהוה, מֶלֶךְ מְהֻלָּל בַּתִּשְׁבָּחוֹת.\n\n\nהוֹדוּ לַיהוה קִרְאוֹ בִשְׁמוֹ, הוֹדִיעוּ בָעַמִּים עֲלִילוֹתָיו: שִׁירוּ לוֹ זַמְּרוּ לוֹ, שִׂיחוּ בְּכָל נִפְלְאוֹתָיו: הִתְהַלְלוּ בְּשֵׁם קָדְשׁוֹ, יִשְׂמַח לֵב מְבַקְשֵׁי יהוה: דִּרְשׁוּ יהוה וְעֻזּוֹ, בַּקְּשׁוּ פָנָיו תָּמִיד: זִכְרוּ נִפְלְאוֹתָיו אֲשֶׁר עָשָׂה, מֹפְתָיו וּמִשְׁפְּטֵי פִיהוּ: זֶרַע יִשְׂרָאֵל עַבְדּוֹ, בְּנֵי יַעֲקֹב בְּחִירָיו: הוּא יהוה אֱלֹהֵינוּ בְּכָל הָאָרֶץ מִשְׁפָּטָיו: זִכְרוּ לְעוֹלָם בְּרִיתוֹ, דָּבָר צִוָּה לְאֶלֶף דּוֹר: אֲשֶׁר כָּרַת אֶת אַבְרָהָם, וּשְׁבוּעָתוֹ לְיִצְחָק: וַיַּעֲמִידֶהָ לְיַעֲקֹב לְחֹק, לְיִשְׂרָאֵל בְּרִית עוֹלָם: לֵאמֹר, לְךָ אֶתֵּן אֶרֶץ כְּנָעַן, חֶבֶל נַחֲלַתְכֶם: בִּהְיוֹתְכֶם מְתֵי מִסְפָּר, כִּמְעַט וְגָרִים בָּהּ: וַיִּתְהַלְּכוּ מִגּוֹי אֶל גּוֹי וּמִמַּמְלָכָה אֶל עַם אַחֵר: לֹא הִנִּיחַ לְאִישׁ לְעָשְׁקָם, וַיּוֹכַח עֲלֵיהֶם מְלָכִים: אַל תִּגְּעוּ בִּמְשִׁיחָי, וּבִנְבִיאַי אַל תָּרֵעוּ: שִׁירוּ לַיהוה כָּל הָאָרֶץ, בַּשְּׂרוּ מִיּוֹם אֶל יוֹם יְשׁוּעָתוֹ: סַפְּרוּ בַגּוֹיִם אֶת כְּבוֹדוֹ, בְּכָל הָעַמִּים נִפְלְאֹתָיו: כִּי גָדוֹל יהוה וּמְהֻלָּל מְאֹד, וְנוֹרָא הוּא עַל כָּל אֱלֹהִים: כִּי כָּל אֱלֹהֵי הָעַמִּים אֱלִילִים, וַיהוה שָׁמַיִם עָשָׂה: הוֹד וְהָדָר לְפָנָיו, עֹז וְחֶדְוָה בִּמְקֹמוֹ: הָבוּ לַיהוה מִשְׁפְּחוֹת עַמִּים, הָבוּ לַיהוה כָּבוֹד וָעֹז: הָבוּ לַיהוה כְּבוֹד שְׁמוֹ, שְׂאוּ מִנְחָה וּבֹאוּ לְפָנָיו, הִשְׁתַּחֲווּ לַיהוה בְּהַדְרַת קֹדֶשׁ: חִילוּ מִלְּפָנָיו כָּל הָאָרֶץ, אַף תִּכּוֹן תֵּבֵל בַּל תִּמּוֹט: יִשְׂמְחוּ הַשָּׁמַיִם וְתָגֵל הָאָרֶץ, וְיֹאמְרוּ בַגּוֹיִם יהוה מָלָךְ: יִרְעַם הַיָּם וּמְלוֹאוֹ, יַעֲלֹץ הַשָּׂדֶה וְכָל אֲשֶׁר בּוֹ: אָז יְרַנְּנוּ עֲצֵי הַיָּעַר מִלִּפְנֵי יהוה, כִּי בָא לִשְׁפּוֹט אֶת הָאָרֶץ: הוֹדוּ לַיהוה כִּי טוֹב, כִּי לְעוֹלָם חַסְדּוֹ: וְאִמְרוּ, הוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ וְקַבְּצֵנוּ וְהַצִּילֵנוּ מִן הַגּוֹיִם, לְהֹדוֹת לְשֵׁם קָדְשֶׁךָ, לְהִשְׁתַּבֵּחַ בִּתְהִלָּתֶךָ: בָּרוּךְ יהוה אֱלֹהֵי יִשְׂרָאֵל מִן הָעוֹלָם וְעַד הָעֹלָם, וַיֹּאמְרוּ כָל הָעָם אָמֵן וְהַלֵּל לַיהוה: רוֹמְמוּ יהוה אֱלֹהֵינוּ וְהִשְׁתַּחֲווּ לַהֲדֹם רַגְלָיו, קָדוֹשׁ הוּא: רוֹמְמוּ יהוה אֱלֹהֵינוּ וְהִשְׁתַּחֲווּ לְהַר קָדְשׁוֹ, כִּי קָדוֹשׁ יהוה אֱלֹהֵינוּ: וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית, וְהִרְבָּה לְהָשִׁיב אַפּוֹ וְלֹא יָעִיר כָּל חֲמָתוֹ: אַתָּה יהוה לֹא תִכְלָא רַחֲמֶיךָ מִמֶּנִּי, חַסְדְּךָ וַאֲמִתְּךָ תָּמִיד יִצְּרוּנִי: זְכֹר רַחֲמֶיךָ יהוה, וַחֲסָדֶיךָ, כִּי מֵעוֹלָם הֵמָּה: תְּנוּ עֹז לֵאלֹהִים, עַל יִשְׂרָאֵל גַּאֲוָתוֹ וְעֻזּוֹ בַּשְּׁחָקִים: נוֹרָא אֱלֹהִים מִמִּקְדָּשֶׁיךָ אֵל יִשְׂרָאֵל, הוּא נֹתֵן עֹז וְתַעֲצֻמוֹת לָעָם, בָּרוּךְ אֱלֹהִים: אֵל נְקָמוֹת יהוה, אֵל נְקָמוֹת הוֹפִיעַ: הִנָּשֵׂא שֹׁפֵט הָאָרֶץ, הָשֵׁב גְּמוּל עַל גֵּאִים: לַיהוה הַיְשׁוּעָה עַל עַמְּךָ בִרְכָתֶךָ, סֶּלָה: יהוה צְבָאוֹת עִמָּנוּ מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב, סֶלָה: יהוה צְבָאוֹת אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ: הוֹשִׁיעָה אֶת עַמֶּךָ וּבָרֵךְ אֶת נַחֲלָתֶךָ, וּרְעֵם וְנַשְּׂאֵם עַד הָעוֹלָם: נַפְשֵׁנוּ חִכְּתָה לַיהוה, עֶזְרֵנוּ וּמָגִנֵּנוּ הוּא: כִּי בוֹ יִשְׂמַח לִבֵּנוּ כִּי בְשֵׁם קָדְשׁוֹ בָטָחְנוּ: יְהִי חַסְדְּךָ יהוה עָלֵינוּ כַּאֲשֶׁר יִחַלְנוּ לָךְ: הַרְאֵנוּ יהוה חַסְדֶּךָ, וְיֶשְׁעֲךָ תִּתֶּן לָנוּ: קוּמָה עֶזְרָתָה לָּנוּ וּפְדֵנוּ לְמַעַן חַסְדֶּךָ: אָנֹכִי יהוה אֱלֹהֶיךָ הַמַּעַלְךָ מֵאֶרֶץ מִצְרָיִם, הַרְחֶב פִּיךָ וַאֲמַלְאֵהוּ: אַשְׁרֵי הָעָם שֶׁכָּכָה לוֹ, אַשְׁרֵי הָעָם שֶׁיהוה אֱלֹהָיו: וַאֲנִי בְּחַסְדְּךָ בָטַחְתִּי, יָגֵל לִבִּי בִּישׁוּעָתֶךָ, אָשִׁירָה לַיהוה כִּי גָמַל עָלָי:","cond":[]},{"kind":"text","text":"מִזְמוֹר לְתוֹדָה, הָרִיעוּ לַיהוה כָּל הָאָרֶץ: עִבְדוּ אֶת יהוה בְּשִׂמְחָה, בֹּאוּ לְפָנָיו בִּרְנָנָה: דְּעוּ כִּי יהוה הוּא אֱלֹהִים, הוּא עָשָׂנוּ וְלוֹ אֲנַחְנוּ, עַמּוֹ וְצֹאן מַרְעִיתוֹ: בֹּאוּ שְׁעָרָיו בְּתוֹדָה, חֲצֵרֹתָיו בִּתְהִלָּה, הוֹדוּ לוֹ בָּרְכוּ שְׁמוֹ: כִּי טוֹב יהוה, לְעוֹלָם חַסְדּוֹ, וְעַד דֹּר וָדֹר אֱמוּנָתוֹ:","cond":["toda"]},{"kind":"text","text":"לַמְנַצֵּחַ מִזְמוֹר לְדָוִד: הַשָּׁמַיִם מְסַפְּרִים כְּבוֹד אֵל, וּמַעֲשה יָדָיו מַגִּיד הָרָקִיעַ: יוֹם לְיוֹם יַבִּיעַ אֹמֶר, וְלַיְלָה לְלַיְלָה יְחַוֶּה דָּעַת: אֵין אֹמֶר וְאֵין דְּבָרִים, בְּלִי נִשְׁמָע קוֹלָם: בְּכָל הָאָרֶץ יָצָא קַוָּם, וּבִקְצֵה תֵבֵל מִלֵּיהֶם, לַשֶּׁמֶשׁ שָׂם אֹהֶל בָּהֶם: וְהוּא כְּחָתָן יֹצֵא מֵחֻפָּתוֹ, יָשִׂישׂ כְּגִבּוֹר לָרוּץ אֹרַח: מִקְצֵה הַשָּׁמַיִם מוֹצָאוֹ וּתְקוּפָתוֹ עַל קְצוֹתָם, וְאֵין נִסְתָּר מֵחַמָּתוֹ: תּוֹרַת יהוה תְּמִימָה מְשִׁיבַת נָפֶשׁ, עֵדוּת יהוה נֶאֱמָנָה מַחְכִּימַת פֶּתִי: פִּקּוּדֵי יהוה יְשָׁרִים מְשַׂמְּחֵי לֵב, מִצְוַת יהוה בָּרָה מְאִירַת עֵינָיִם: יִרְאַת יהוה טְהוֹרָה עומֶדֶת לָעַד, מִשְׁפְּטֵי יהוה אֱמֶת צָדְקוּ יַחְדָּו: הַנֶחֱמָדִים מִזָּהָב וּמִפָּז רָב, וּמְתוּקִים מִדְּבַשׁ וְנֹפֶת צוּפִים: גַּם עַבְדְּךָ נִזְהָר בָּהֶם, בְּשָׁמְרָם עֵקֶב רָב: שְׁגִיאות מִי יָבִין מִנִּסְתָּרוֹת נַקֵּנִי: גַּם מִזֵּדִים חֲשֹׂךְ עַבְדֶּךָ, אַל יִמְשְׁלוּ בִי אָז אֵיתָם, וְנִקֵּיתִי מִפֶּשַׁע רָב: יִהְיוּ לְרָצון אִמְרֵי פִי וְהֶגְיון לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגֹאֲלִי:\n\nלְדָוִד בְּשַׁנּוֹתו אֶת טַעְמוֹ לִפְנֵי אֲבִימֶלֶךְ, וַיְגָרְשֵׁהוּ וַיֵּלַךְ: אֲבָרְכָה אֶת יהוה בְּכָל עֵת, תָּמִיד תְּהִלָּתוֹ בְּפִי: בַּיהוה תִּתְהַלֵּל נַפְשִׁי, יִשְׁמְעוּ עֲנָוִים וְיִשמָחוּ: גַדְּלוּ לַיהוה אִתִּי, וּנְרוֹמְמָה שְׁמוֹ יַחְדָּו: דָּרַשְׁתִּי אֶת יהוה וְעָנָנִי, וּמִכָּל מְגוּרוֹתַי הִצִּילָנִי: הִבִּיטוּ אֵלָיו וְנָהָרוּ, וּפְנֵיהֶם אַל יֶחְפָּרוּ: זֶה עָנִי קָרָא וַיהוה שָׁמֵעַ, וּמִכָּל צָרוֹתָיו הוֹשִׁיעוֹ: חוֹנֶה מַלְאַךְ יהוה סָבִיב לִירֵאָיו וַיְחַלְּצֵם: טַעֲמוּ וּרְאוּ כִּי טוֹב יהוה, אַשְׁרֵי הַגֶּבֶר יֶחֱסֶה בּוֹ: יְראוּ אֶת יהוה קְדוֹשָׁיו, כִּי אֵין מַחְסוֹר לִירֵאָיו: כְּפִירִים רָשׁוּ וְרָעֵבוּ, וְדוֹרְשֵׁי יהוה לֹא יַחְסְרוּ כָל טוֹב: לְכוּ בָנִים שִׁמְעוּ לִי, יִרְאַת יהוה אֲלַמֶּדְכֶם: מִי הָאִישׁ הֶחָפֵץ חַיִּים, אֹהֵב יָמִים לִרְאוֹת טוֹב: נְצֹר לְשׁוֹנְךָ מֵרָע, וּשפָתֶיךָ מִדַּבֵּר מִרְמָה: סוּר מֵרָע וַעֲשֵׂה טוֹב, בַּקֵּשׁ שָׁלוֹם וְרָדְפֵהוּ: עֵינֵי יהוה אֶל צַדִּיקִים, וְאָזְנָיו אֶל שַׁוְעָתָם: פְּנֵי יהוה בְּעֹשֵׂי רָע, לְהַכְרִית מֵאֶרֶץ זִכְרָם: צָעֲקוּ וַיהוה שָׁמֵעַ, וּמִכָּל צָרוֹתָם הִצִּילָם: קָרוֹב יהוה לְנִשְׁבְּרֵי לֵב, וְאֶת דַּכְּאֵי רוּחַ יוֹשִׁיעַ: רַבּוֹת רָעוֹת צַדִּיק, וּמִכֻּלָּם יַצִּילֶנּוּ יהוה: שֹׁמֵר כָּל עַצְמוֹתָיו, אַחַת מֵהֵנָּה לֹא נִשְׁבָּרָה: תְּמוֹתֵת רָשָׁע רָעָה, וְשֹׂנְאֵי צַדִּיק יֶאְשָׁמוּ: פּוֹדֶה יהוה נֶפֶשׁ עֲבָדָיו, וְלא יֶאְשְׁמוּ כָּל הַחוֹסִים בּוֹ:\n\nתְּפִלָּה לְמֹשֶׁה אִישׁ הָאֱלֹהִים, אֲדֹנָי מָעוֹן אַתָּה הָיִיתָ לָּנוּ, בְּדוֹר וָדֹר: בְּטֶרֶם הָרִים יֻלָּדוּ וַתְּחוֹלֵל אֶרֶץ וְתֵבֵל, וּמֵעוֹלָם עַד עוֹלָם אַתָּה אֵל: תָּשֵׁב אֱנוֹשׁ עַד דַּכָּא, וַתֹּאמֶר שׁוּבוּ בְנֵי אָדָם: כִּי אֶלֶף שָׁנִים בְּעֵינֶיךָ כְּיוֹם אֶתְמול כִּי יַעֲבֹר, וְאַשְׁמוּרָה בַלָּיְלָה: זְרַמְתָּם שֵׁנָה יִהְיוּ, בַּבֹּקֶר כֶּחָצִיר יַחֲלֹף: בַּבֹּקֶר יָצִיץ וְחָלָף, לָעֶרֶב יְמוֹלֵל וְיָבֵשׁ: כִּי כָלִינוּ בְאַפֶּךָ, וּבַחֲמָתְךָ נִבְהָלְנוּ: שַׁתָּה עֲוׂנוֹתֵינוּ לְנֶגְדֶּךָ, עֲלֻמֵנוּ לִמְאוֹר פָּנֶיךָ: כִּי כָל יָמֵינוּ פָּנוּ בְעֶבְרָתֶךָ, כִּלִּינוּ שָׁנֵינוּ כְּמוֹ הֶגֶה: יְמֵי שְׁנוֹתֵינוּ בָּהֶם שִׁבְעִים שָׁנָה, וְאִם בִּגְבוּרֹת שְׁמוֹנִים שָׁנָה, וְרָהְבָּם עָמָל וָאָוֶן, כִּי גָז חִישׁ וַנָּעֻפָה: מִי יוֹדֵעַ עֹז אַפֶּךָ, וּכְיִרְאָתְךָ עֶבְרָתֶךָ: לִמְנוֹת יָמֵינוּ כֵּן הוֹדַע, וְנָבִיא לְבַב חָכְמָה: שׁוּבָה יהוה עַד מָתָי, וְהִנָּחֵם עַל עֲבָדֶיךָ: שַׂבְּעֵנוּ בַבֹּקֶר חַסְדֶּךָ, וּנְרַנְּנָה וְנִשמְחָה בְּכָל יָמֵינוּ: שַׂמְּחֵנוּ כִּימות עִנִּיתָנוּ, שְׁנוֹת רָאִינוּ רָעָה: יֵרָאֶה אֶל עֲבָדֶיךָ פָעֳלֶךָ, וַהֲדָרְךָ עַל בְּנֵיהֶם: וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ:\n\nיֹשֵׁב בְּסֵתֶר עֶלְיוֹן, בְּצֵל שַׁדַּי יִתְלוֹנָן: אֹמַר לַיהוה מַחְסִי וּמְצוּדָתִי, אֱלֹהַי אֶבְטַח בּוֹ: כִּי הוּא יַצִּילְךָ מִפַּח יָקוּשׁ, מִדֶּבֶר הַוּוֹת: בְּאֶבְרָתו יָסֶךְ לָךְ, וְתַחַת כְּנָפָיו תֶּחְסֶה, צִנָּה וְסוֹחֵרָה אֲמִתּוֹ: לא תִירָא מִפַּחַד לָיְלָה, מֵחֵץ יָעוּף יוֹמָם: מִדֶּבֶר בָּאֹפֶל יַהֲלֹךְ, מִקֶּטֶב יָשׁוּד צָהֳרָיִם: יִפֹּל מִצִּדְּךָ אֶלֶף וּרְבָבָה מִימִינֶךָ, אֵלֶיךָ לֹא יִגָּשׁ: רַק בְּעֵינֶיךָ תַבִּיט, וְשִׁלֻּמַת רְשָׁעִים תִּרְאֶה: כִּי אַתָּה יהוה מַחְסִי, עֶלְיוֹן שמְתָּ מְעוֹנֶךָ: לא תְאֻנֶּה אֵלֶיךָ רָעָה, וְנֶגַע לא יִקְרַב בְּאָהֳלֶךָ: כִּי מַלְאָכָיו יְצַוֶּה לָּךְ, לִשְׁמָרְךָ בְּכָל דְּרָכֶיךָ: עַל כַּפַּיִם יִשָּׂאוּנְךָ, פֶּן תִּגּוֹף בָּאֶבֶן רַגְלֶךָ: עַל שַׁחַל וָפֶתֶן תִּדְרוֹךְ, תִּרְמוֹס כְּפִיר וְתַנִּין: כִּי בִי חָשַׁק וַאֲפַלְּטֵהוּ, אֲשַׂגְּבֵהוּ כִּי יָדַע שְׁמִי: יִקְרָאֵנִי וְאֶעֱנֵהוּ, עִמּוֹ אָנֹכִי בְצָרָה, אֲחַלְּצֵהוּ וַאֲכַבְּדֵהוּ: אֹרֶךְ יָמִים אַשְׂבִּיעֵהוּ, וְאַרְאֵהוּ בִּישׁוּעָתִי: אֹרֶךְ יָמִים אַשְׂבִּיעֵהוּ, וְאַרְאֵהוּ בִּישׁוּעָתִי:\n\nהַלְלוּיָהּ, הַלְלוּ אֶת שֵׁם יהוה, הַלְלוּ עַבְדֵי יהוה: שֶׁעוֹמְדִים בְּבֵית יהוה, בְּחַצְרוֹת בֵּית אֱלֹהֵינוּ: הַלְלוּיָהּ כִּי טוֹב יהוה, זַמְּרוּ לִשְׁמוֹ כִּי נָעִים: כִּי יַעֲקֹב בָּחַר לוֹ יָהּ, יִשְׂרָאֵל לִסְגֻלָּתו: כִּי אֲנִי יָדַעְתִּי כִּי גָּדוֹל יהוה, וַאֲדֹנֵינוּ מִכָּל אֱלֹהִים: כֹּל אֲשֶׁר חָפֵץ יהוה עָשָׂה, בַּשָּׁמַיִם וּבָאָרֶץ בַּיַּמִּים וְכָל תְּהֹמֹת: מַעֲלֶה נְשִׂאִים מִקְצֵה הָאָרֶץ, בְּרָקִים לַמָּטָר עָשָׂה, מוֹצֵא רוּחַ מֵאוֹצְרוֹתָיו: שֶׁהִכָּה בְּכוֹרֵי מִצְרָיִם, מֵאָדָם עַד בְּהֵמָה: שָׁלַח אוֹתֹת וּמוֹפְתִים בְּתוֹכֵכִי מִצְרָיִם, בְּפַרְעֹה וּבְכָל עֲבָדָיו: שֶׁהִכָּה גּוֹיִם רַבִּים, וְהָרַג מְלָכִים עֲצוּמִים: לְסִיחוֹן מֶלֶךְ הָאֱמֹרִי וּלְעוֹג מֶלֶךְ הַבָּשָׁן, וּלְכֹל מַמְלְכוֹת כְּנָעַן: וְנָתַן אַרְצָם נַחֲלָה, נַחֲלָה לְיִשְׂרָאֵל עַמּוֹ: יהוה שִׁמְךָ לְעוֹלָם, יהוה זִכְרְךָ לְדֹר וָדֹר: כִּי יָדִין יהוה עַמּוֹ, וְעַל עֲבָדָיו יִתְנֶחָם: עֲצַבֵּי הַגּוֹיִם כֶּסֶף וְזָהָב, מַעֲשֵׂה יְדֵי אָדָם: פֶּה לָהֶם וְלֹא יְדַבֵּרוּ, עֵינַיִם לָהֶם וְלֹא יִרְאוּ: אָזְנַיִם לָהֶם וְלֹא יַאֲזִינוּ, אַף אֵין יֶשׁ רוּחַ בְּפִיהֶם: כְּמוֹהֶם יִהְיוּ עֹשֵׂיהֶם, כֹּל אֲשֶׁר בֹּטֵחַ בָּהֶם: בֵּית יִשְׂרָאֵל בָּרְכוּ אֶת יהוה, בֵּית אַהֲרֹן בָּרְכוּ אֶת יהוה: בֵּית הַלֵּוִי בָּרְכוּ אֶת יהוה, יִרְאֵי יהוה בָּרְכוּ אֶת יהוה: בָּרוּךְ יהוה מִצִּיּוֹן, שֹׁכֵן יְרוּשָׁלָיִם, הַלְלוּיָהּ:\n\nהוֹדוּ ליהוה כִּי טוֹב, כִּי לְעוֹלָם חַסְדּו:\nהוֹדוּ לֵאלֹהֵי הָאֱלֹהִים, כִּי לְעוֹלָם חַסְדּוֹ:\nהוֹדוּ לַאֲדֹנֵי הָאֲדֹנִים, כִּי לְעוֹלָם חַסְדּוֹ:\nלְעֹשֵׂה נִפְלָאוֹת גְּדֹלוֹת לְבַדּוֹ, כִּי לְעוֹלָם חַסְדּוֹ:\nלְעֹשֵׂה הַשָּׁמַיִם בִּתְבוּנָה, כִּי לְעוֹלָם חַסְדּוֹ:\nלְרוֹקַע הָאָרֶץ עַל הַמָּיִם, כִּי לְעוֹלָם חַסְדּוֹ:\nלְעֹשֵׂה אוֹרִים גְּדֹלִים, כִּי לְעוֹלָם חַסְדּוֹ:\nאֶת הַשֶּׁמֶשׁ לְמֶמְשֶׁלֶת בַּיּוֹם, כִּי לְעוֹלָם חַסְדּוֹ:\nאֶת הַיָּרֵחַ וְכוֹכָבִים לְמֶמְשְׁלוֹת בַּלָּיְלָה, כִּי לְעוֹלָם חַסְדּוֹ:\nלְמַכֵּה מִצְרַיִם בִּבְכוֹרֵיהֶם, כִּי לְעוֹלָם חַסְדּוֹ:\nוַיּוֹצֵא יִשְׂרָאֵל מִתּוֹכָם, כִּי לְעוֹלָם חַסְדּוֹ:\nבְּיָד חֲזָקָה וּבִזְרוֹעַ נְטוּיָה, כִּי לְעוֹלָם חַסְדּוֹ:\nלְגֹזֵר יַם סוּף לִגְזָרִים, כִּי לְעוֹלָם חַסְדּוֹ:\nוְהֶעֱבִיר יִשְׂרָאֵל בְּתוֹכוֹ, כִּי לְעוֹלָם חַסְדּוֹ:\nוְנִעֵר פַּרְעֹה וְחֵילוֹ בְיַם סוּף, כִּי לְעוֹלָם חַסְדּוֹ:\nלְמוֹלִיךְ עַמּוֹ בַּמִּדְבָּר, כִּי לְעוֹלָם חַסְדּוֹ:\nלְמַכֵּה מְלָכִים גְּדֹלִים, כִּי לְעוֹלָם חַסְדּוֹ:\nוַיַּהֲרֹג מְלָכִים אַדִּירִים, כִּי לְעוֹלָם חַסְדּוֹ:\nלְסִיחוֹן מֶלֶךְ הָאֱמֹרִי, כִּי לְעוֹלָם חַסְדּוֹ:\nוּלְעוֹג מֶלֶךְ הַבָּשָׁן, כִּי לְעוֹלָם חַסְדּוֹ:\nוְנָתַן אַרְצָם לְנַחֲלָה, כִּי לְעוֹלָם חַסְדּוֹ:\nנַחֲלָה לְיִשְׂרָאֵל עַבְדּוֹ, כִּי לְעוֹלָם חַסְדּוֹ:\nשֶׁבְּשִׁפְלֵנוּ זָכַר לָנוּ, כִּי לְעוֹלָם חַסְדּוֹ:\nוַיִּפְרְקֵנוּ מִצָּרֵינוּ, כִּי לְעוֹלָם חַסְדּוֹ:\nנוֹתֵן לֶחֶם לְכָל בָּשָׂר, כִּי לְעוֹלָם חַסְדּוֹ:\nהוֹדוּ לְאֵל הַשָּׁמָיִם, כִּי לְעוֹלָם חַסְדּוֹ:\n\nרַנְּנוּ צַדִּיקִים בַּיהוה, לַיְשָׁרִים נָאוָה תְהִלָּה: הוֹדוּ לַיהוה בְּכִנּוֹר, בְּנֵבֶל עָשׂוֹר זַמְּרוּ לוֹ: שִׁירוּ לוֹ שִׁיר חָדָשׁ, הֵיטִיבוּ נַגֵּן בִּתְרוּעָה: כִּי יָשָׁר דְּבַר יהוה, וְכָל מַעֲשֵׂהוּ בֶּאֱמוּנָה: אֹהֵב צְדָקָה וּמִשְׁפָּט, חֶסֶד יהוה מָלְאָה הָאָרֶץ: בִּדְבַר יהוה שָׁמַיִם נַעֲשׂוּ, וּבְרוּחַ פִּיו כָּל צְבָאָם: כֹּנֵס כַּנֵּד מֵי הַיָּם, נֹתֵן בְּאוֹצָרוֹת תְּהוֹמוֹת: יִירְאוּ מֵיהוה כָּל הָאָרֶץ, מִמֶּנּוּ יָגוּרוּ כָּל יֹשְׁבֵי תֵבֵל: כִּי הוּא אָמַר וַיֶּהִי, הוּא צִוָּה וַיַּעֲמֹד: יהוה הֵפִיר עֲצַת גּוֹיִם, הֵנִיא מַחְשְׁבוֹת עַמִּים: עֲצַת יהוה לְעוֹלָם תַּעֲמֹד, מַחְשְׁבוֹת לִבּוֹ לְדֹר וָדֹר: אַשְׁרֵי הַגּוֹי אֲשֶׁר יהוה אֱלֹהָיו, הָעָם בָּחַר לְנַחֲלָה לוֹ: מִשָּׁמַיִם הִבִּיט יהוה, רָאָה אֶת כָּל בְּנֵי הָאָדָם: מִמְּכוֹן שִׁבְתּוֹ הִשְׁגִּיחַ אֶל כָּל יֹשְׁבֵי הָאָרֶץ: הַיּוֹצֵר יַחַד לִבָּם, הַמֵּבִין אֶל כָּל מַעֲשֵׂיהֶם: אֵין הַמֶּלֶךְ נוֹשָׁע בְּרָב חָיִל, גִּבּוֹר לא יִנָּצֵל בְּרָב כֹּחַ: שֶׁקֶר הַסּוּס לִתְשׁוּעָה, וּבְרֹב חֵילוֹ לֹא יְמַלֵּט: הִנֵּה עֵין יהוה אֶל יְרֵאָיו, לַמְיַחֲלִים לְחַסְדּוֹ: לְהַצִּיל מִמָּוֶת נַפְשָׁם, וּלְחַיּוֹתָם בָּרָעָב: נַפְשֵׁנוּ חִכְּתָה לַיהוה, עֶזְרֵנוּ וּמָגִנֵּנוּ הוּא: כִּי בוֹ יִשְׂמַח לִבֵּנוּ, כִּי בְשֵׁם קָדְשׁו בָטָחְנוּ: יְהִי חַסְדְּךָ יהוה עָלֵינוּ, כַּאֲשֶׁר יִחַלְנוּ לָךְ:\n\nמִזְמוֹר שִׁיר לְיוֹם הַשַּׁבָּת: טוֹב לְהוֹדוֹת לַיהוה, וּלְזַמֵּר לְשִׁמְךָ עֶלְיוֹן: לְהַגִּיד בַּבֹּקֶר חַסְדֶּךָ, וֶאֱמוּנָתְךָ בַּלֵּילוֹת: עֲלֵי עָשׂוֹר וַעֲלֵי נָבֶל, עֲלֵי הִגָּיוֹן בְּכִנּוֹר: כִּי שִׂמַּחְתַּנִי יהוה בְּפָעֳלֶךָ, בְּמַעֲשֵׂי יָדֶיךָ אֲרַנֵּן: מַה גָּדְלוּ מַעֲשֶׂיךָ יהוה, מְאֹד עָמְקוּ מַחְשְׁבֹתֶיךָ: אִישׁ בַּעַר לֹא יֵדָע, וּכְסִיל לֹא יָבִין אֶת זֹאת: בִּפְרֹחַ רְשָׁעִים כְּמוֹ עֵשֶׂב, וַיָּצִיצוּ כָּל פֹּעֲלֵי אָוֶן, לְהִשָּׁמְדָם עֲדֵי עַד: וְאַתָּה מָרוֹם לְעוֹלָם יהוה: כִּי הִנֵּה אֹיְבֶיךָ יהוה, כִּי הִנֵּה אֹיְבֶיךָ יֹאבֵדוּ, יִתְפָּרְדוּ כָּל פֹּעֲלֵי אָוֶן: וַתָּרֶם כִּרְאֵים קַרְנִי, בַּלֹּתִי בְּשֶׁמֶן רַעֲנָן: וַתַּבֵּט עֵינִי בְּשׁוּרָי, בַּקָּמִים עָלַי מְרֵעִים תִּשְׁמַעְנָה אָזְנָי: צַדִּיק כַּתָּמָר יִפְרָח, כְּאֶרֶז בַּלְּבָנוֹן יִשְׂגֶּה: שְׁתוּלִים בְּבֵית יהוה, בְּחַצְרוֹת אֱלֹהֵינוּ יַפְרִיחוּ: עוֹד יְנוּבוּן בְּשֵׂיבָה, דְּשֵׁנִים וְרַעֲנַנִּים יִהְיוּ: לְהַגִּיד כִּי יָשָׁר יהוה, צוּרִי וְלֹא עַוְלָתָה בּוֹ:\n\nיהוה מָלָךְ גֵּאוּת לָבֵשׁ, לָבֵשׁ יהוה עֹז הִתְאַזָּר, אַף תִּכּוֹן תֵּבֵל בַּל תִּמּוֹט: נָכוֹן כִּסְאֲךָ מֵאָז, מֵעוֹלָם אָתָּה: נָשְׂאוּ נְהָרוֹת, יהוה, נָשְׂאוּ נְהָרוֹת קוֹלָם, יִשְׂאוּ נְהָרוֹת דָכְיָם: מִקֹּלוֹת מַיִם רַבִּים, אַדִּירִים מִשְׁבְּרֵי יָם, אַדִּיר בַּמָּרוֹם יהוה: עֵדֹתֶיךָ נֶאֶמְנוּ מְאֹד לְבֵיתְךָ נַאֲוָה קֹדֶשׁ, יהוה, לְאֹרֶךְ יָמִים:","cond":["shabbat"]},{"kind":"text","text":"יְהִי כְבוֹד יהוה לְעוֹלָם, יִשְׂמַח יהוה בְּמַעֲשָׂיו: יְהִי שֵׁם יהוה מְבֹרָךְ מֵעַתָּה וְעַד עוֹלָם: מִמִּזְרַח שֶׁמֶשׁ עַד מְבוֹאוֹ מְהֻלָּל שֵׁם יהוה: רָם עַל כָּל גּוֹיִם יהוה, עַל הַשָּׁמַיִם כְּבוֹדוֹ: יהוה שִׁמְךָ לְעוֹלָם, יהוה זִכְרְךָ לְדֹר וָדֹר: יהוה בַּשָּׁמַיִם הֵכִין כִּסְאוֹ וּמַלְכוּתוֹ בַּכֹּל מָשָׁלָה: יִשְׂמְחוּ הַשָּׁמַיִם וְתָגֵל הָאָרֶץ, וְיֹאמְרוּ בַגּוֹיִם יהוה מָלָךְ: יהוה מֶלֶךְ, יהוה מָלָךְ, יהוה יִמְלֹךְ לְעוֹלָם וָעֶד. יהוה מֶלֶךְ עוֹלָם וָעֶד, אָבְדוּ גוֹיִם מֵאַרְצוֹ: יהוה הֵפִיר עֲצַת גּוֹיִם, הֵנִיא מַחְשְׁבוֹת עַמִּים: רַבּוֹת מַחֲשָׁבוֹת בְּלֶב אִישׁ, וַעֲצַת יהוה הִיא תָקוּם: עֲצַת יהוה לְעוֹלָם תַּעֲמֹד, מַחְשְׁבוֹת לִבּוֹ לְדֹר וָדֹר: כִּי הוּא אָמַר וַיֶּהִי, הוּא צִוָּה וַיַּעֲמֹד: כִּי בָחַר יהוה בְּצִיּוֹן, אִוָּהּ לְמוֹשָׁב לוֹ: כִּי יַעֲקֹב בָּחַר לוֹ יָהּ, יִשְׂרָאֵל לִסְגֻלָּתוֹ: כִּי לֹא יִטֹּשׁ יהוה עַמּוֹ וְנַחֲלָתוֹ לֹא יַעֲזֹב: וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית, וְהִרְבָּה לְהָשִׁיב אַפּוֹ וְלֹא יָעִיר כָּל חֲמָתוֹ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":[]},{"kind":"header","text":"אשרי","cond":[]},{"kind":"text","text":"אַשְׁרֵי יוֹשְׁבֵי בֵיתֶךָ עוֹד יְהַלְלוּךָ סֶּלָה:\nאַשְׁרֵי הָעָם שֶׁכָּכָה לּוֹ אַשְׁרֵי הָעָם שֶׁיהוה אֱלֹהָיו:\nתְּהִלָּה לְדָוִד, אֲרוֹמִמְךָ אֱלוֹהַי הַמֶּלֶךְ וַאֲבָרְכָה שִׁמְךָ לְעוֹלָם וָעֶד:\nבְּכָל יוֹם אֲבָרְכֶךָּ וַאֲהַלְלָה שִׁמְךָ לְעוֹלָם וָעֶד:\nגָּדוֹל יהוה וּמְהֻלָּל מְאֹד וְלִגְדֻלָּתוֹ אֵין חֵקֶר:\nדּוֹר לְדוֹר יְשַׁבַּח מַעֲשֶׂיךָ וּגְבוּרֹתֶיךָ יַגִּידוּ:\nהֲדַר כְּבוֹד הוֹדֶךָ וְדִבְרֵי נִפְלְאוֹתֶיךָ אָשִׂיחָה:\nוֶעֱזוּז נוֹרְאֹתֶיךָ יֹאמֵרוּ וּגְדוּלָּתְךָ אֲסַפְּרֶנָּה:\nזֵכֶר רַב טוּבְךָ יַבִּיעוּ וְצִדְקָתְךָ יְרַנֵּנוּ:","cond":[]},{"kind":"text","text":"חַנּוּן וְרַחוּם יהוה אֶרֶךְ אַפַּיִם וּגְדָל חָסֶד:\nטוֹב יהוה לַכֹּל וְרַחֲמָיו עַל כָּל מַעֲשָׂיו:\nיוֹדוּךָ יהוה כָּל מַעֲשֶׂיךָ וַחֲסִידֶיךָ יְבָרְכוּכָה:\nכְּבוֹד מַלְכוּתְךָ יֹאמֵרוּ וּגְבוּרָתְךָ יְדַבֵּרוּ:\nלְהוֹדִיעַ לִבְנֵי הָאָדָם גְּבוּרֹתָיו וּכְבוֹד הֲדַר מַלְכוּתוֹ:\nמַלְכוּתְךָ מַלְכוּת כָּל עֹלָמִים וּמֶמְשַׁלְתְּךָ בְּכָל דּוֹר וָדוֹר:\nסוֹמֵךְ יהוה לְכָל הַנֹּפְלִים וְזוֹקֵף לְכָל הַכְּפוּפִים:\nעֵינֵי כֹל אֵלֶיךָ יְשַׂבֵּרוּ וְאַתָּה נוֹתֵן לָהֶם אֶת אָכְלָם בְּעִתּוֹ:","cond":[]},{"kind":"text","text":"פּוֹתֵחַ אֶת יָדֶךָ וּמַשְׂבִּיעַ לְכָל חַי רָצוֹן:\nצַדִּיק יהוה בְּכָל דְּרָכָיו וְחָסִיד בְּכָל מַעֲשָׂיו:\nקָרוֹב יהוה לְכָל קֹרְאָיו לְכֹל אֲשֶׁר יִקְרָאֻהוּ בֶאֱמֶת:\nרְצוֹן יְרֵאָיו יַעֲשֶׂה וְאֶת שַׁוְעָתָם יִשְׁמַע וְיוֹשִׁיעֵם:\nשׁוֹמֵר יהוה אֶת כָּל אֹהֲבָיו וְאֵת כָּל הָרְשָׁעִים יַשְׁמִיד:\nתְּהִלַּת יהוה יְדַבֶּר פִּי וִיבָרֵךְ כָּל בָּשָׂר שֵׁם קָדְשׁוֹ לְעוֹלָם וָעֶד:\nוַאֲנַחְנוּ נְבָרֵךְ יָהּ מֵעַתָּה וְעַד עוֹלָם הַלְלוּיָהּ:","cond":[]},{"kind":"text","text":"הַלְלוּיָהּ, הַלְלִי נַפְשִׁי אֶת יהוה: אֲהַלְלָה יהוה בְּחַיָּי, אֲזַמְּרָה לֵאלֹהַי בְּעוֹדִי: אַל תִּבְטְחוּ בִנְדִיבִים, בְּבֶן אָדָם שֶׁאֵין לוֹ תְשׁוּעָה: תֵּצֵא רוּחוֹ, יָשֻׁב לְאַדְמָתוֹ, בַּיּוֹם הַהוּא אָבְדוּ עֶשְׁתֹּנֹתָיו: אַשְׁרֵי שֶׁאֵל יַעֲקֹב בְּעֶזְרוֹ, שִׂבְרוֹ עַל יהוה אֱלֹהָיו: עֹשֶׂה שָׁמַיִם וָאָרֶץ, אֶת הַיָּם וְאֶת כָּל אֲשֶׁר בָּם, הַשֹּׁמֵר אֱמֶת לְעוֹלָם: עֹשֶׂה מִשְׁפָּט לָעֲשׁוּקִים, נֹתֵן לֶחֶם לָרְעֵבִים, יהוה מַתִּיר אֲסוּרִים: יהוה פֹּקֵחַ עִוְרִים, יהוה זֹקֵף כְּפוּפִים, יהוה אֹהֵב צַדִּיקִים: יהוה שֹׁמֵר אֶת גֵּרִים, יָתוֹם וְאַלְמָנָה יְעוֹדֵד וְדֶרֶךְ רְשָׁעִים יְעַוֵּת: יִמְלֹךְ יהוה לְעוֹלָם, אֱלֹהַיִךְ צִיּוֹן לְדֹר וָדֹר, הַלְלוּיָהּ:","cond":[]},{"kind":"text","text":"הַלְלוּיָהּ, כִּי טוֹב זַמְּרָה אֱלֹהֵינוּ, כִּי נָעִים נָאוָה תְהִלָּה: בּוֹנֵה יְרוּשָׁלַיִם יהוה, נִדְחֵי יִשְׂרָאֵל יְכַנֵּס: הָרֹפֵא לִשְׁבוּרֵי לֵב וּמְחַבֵּשׁ לְעַצְּבוֹתָם: מוֹנֶה מִסְפָּר לַכּוֹכָבִים, לְכֻלָּם שֵׁמוֹת יִקְרָא: גָּדוֹל אֲדוֹנֵינוּ וְרַב כֹּחַ, לִתְבוּנָתוֹ אֵין מִסְפָּר: מְעוֹדֵד עֲנָוִים יהוה, מַשְׁפִּיל רְשָׁעִים עֲדֵי אָרֶץ: עֱנוּ לַיהוה בְּתוֹדָה, זַמְּרוּ לֵאלֹהֵינוּ בְכִנּוֹר: הַמְכַסֶּה שָׁמַיִם בְּעָבִים, הַמֵּכִין לָאָרֶץ מָטָר, הַמַּצְמִיחַ הָרִים חָצִיר: נוֹתֵן לִבְהֵמָה לַחְמָהּ, לִבְנֵי עֹרֵב אֲשֶׁר יִקְרָאוּ: לֹא בִגְבוּרַת הַסּוּס יֶחְפָּץ, לֹא בְשׁוֹקֵי הָאִישׁ יִרְצֶה: רוֹצֶה יהוה אֶת יְרֵאָיו, אֶת הַמְיַחֲלִים לְחַסְדּוֹ: שַׁבְּחִי יְרוּשָׁלַיִם אֶת יהוה, הַלְלִי אֱלֹהַיִךְ צִיּוֹן: כִּי חִזַּק בְּרִיחֵי שְׁעָרָיִךְ, בֵּרַךְ בָּנַיִךְ בְּקִרְבֵּךְ: הַשָּׂם גְּבוּלֵךְ שָׁלוֹם, חֵלֶב חִטִּים יַשְׂבִּיעֵךְ: הַשֹּׁלֵחַ אִמְרָתוֹ אָרֶץ, עַד מְהֵרָה יָרוּץ דְּבָרוֹ: הַנֹּתֵן שֶׁלֶג כַּצָּמֶר, כְּפוֹר כָּאֵפֶר יְפַזֵּר: מַשְׁלִיךְ קַרְחוֹ כְפִתִּים, לִפְנֵי קָרָתוֹ מִי יַעֲמֹד: יִשְׁלַח דְּבָרוֹ וְיַמְסֵם, יַשֵּׁב רוּחוֹ יִזְּלוּ מָיִם: מַגִּיד דְּבָרָיו לְיַעֲקֹב, חֻקָּיו וּמִשְׁפָּטָיו לְיִשְׂרָאֵל: לֹא עָשָׂה כֵן לְכָל גּוֹי, וּמִשְׁפָּטִים בַּל יְדָעוּם, הַלְלוּיָהּ:","cond":[]},{"kind":"text","text":"הַלְלוּיָהּ, הַלְלוּ אֶת יהוה מִן הַשָּׁמַיִם, הַלְלוּהוּ בַּמְּרוֹמִים: הַלְלוּהוּ כָל מַלְאָכָיו, הַלְלוּהוּ כָּל צְבָאָיו: הַלְלוּהוּ שֶׁמֶשׁ וְיָרֵחַ, הַלְלוּהוּ כָּל כּוֹכְבֵי אוֹר: הַלְלוּהוּ שְׁמֵי הַשָּׁמָיִם וְהַמַּיִם אֲשֶׁר מֵעַל הַשָּׁמָיִם: יְהַלְלוּ אֶת שֵׁם יהוה, כִּי הוּא צִוָּה וְנִבְרָאוּ: וַיַּעֲמִידֵם לָעַד לְעוֹלָם, חָק נָתַן וְלֹא יַעֲבוֹר: הַלְלוּ אֶת יהוה מִן הָאָרֶץ, תַּנִּינִים וְכָל תְּהֹמוֹת: אֵשׁ וּבָרָד, שֶׁלֶג וְקִיטוֹר, רוּחַ סְעָרָה עֹשָׂה דְבָרוֹ: הֶהָרִים וְכָל גְּבָעוֹת, עֵץ פְּרִי וְכָל אֲרָזִים: הַחַיָּה וְכָל בְּהֵמָה, רֶמֶשׂ וְצִפּוֹר כָּנָף: מַלְכֵי אֶרֶץ וְכָל לְאֻמִּים, שָׂרִים וְכָל שֹׁפְטֵי אָרֶץ: בַּחוּרִים וְגַם בְּתוּלוֹת, זְקֵנִים עִם נְעָרִים: יְהַלְלוּ אֶת שֵׁם יהוה כִּי נִשְׂגָּב שְׁמוֹ לְבַדּוֹ, הוֹדוֹ עַל אֶרֶץ וְשָׁמָיִם: וַיָּרֶם קֶרֶן לְעַמּוֹ, תְּהִלָּה לְכָל חֲסִידָיו, לִבְנֵי יִשְׂרָאֵל עַם קְרֹבוֹ, הַלְלוּיָהּ:","cond":[]},{"kind":"text","text":"הַלְלוּיָהּ, שִׁירוּ לַיהוה שִׁיר חָדָשׁ, תְּהִלָּתוֹ בִּקְהַל חֲסִידִים: יִשְׂמַח יִשְׂרָאֵל בְּעֹשָׂיו, בְּנֵי צִיּוֹן יָגִילוּ בְמַלְכָּם: יְהַלְלוּ שְׁמוֹ בְמָחוֹל, בְּתֹף וְכִנּוֹר יְזַמְּרוּ לוֹ: כִּי רוֹצֶה יהוה בְּעַמּוֹ, יְפָאֵר עֲנָוִים בִּישׁוּעָה: יַעְלְזוּ חֲסִידִים בְּכָבוֹד, יְרַנְּנוּ עַל מִשְׁכְּבוֹתָם: רוֹמְמוֹת אֵל בִּגְרוֹנָם וְחֶרֶב פִּיפִיּוֹת בְּיָדָם: לַעֲשׂוֹת נְקָמָה בַּגּוֹיִם, תּוֹכֵחֹת בַּלְאֻמִּים: לֶאְסֹר מַלְכֵיהֶם בְּזִקִּים וְנִכְבְּדֵיהֶם בְּכַבְלֵי בַרְזֶל: לַעֲשׂוֹת בָּהֶם מִשְׁפָּט כָּתוּב, הָדָר הוּא לְכָל חֲסִידָיו, הַלְלוּיָהּ:","cond":[]},{"kind":"text","text":"הַלְלוּיָהּ, הַלְלוּ אֵל בְּקָדְשׁוֹ, הַלְלוּהוּ בִּרְקִיעַ עֻזּוֹ: הַלְלוּהוּ בִגְבוּרֹתָיו, הַלְלוּהוּ כְּרֹב גֻּדְלוֹ: הַלְלוּהוּ בְּתֵקַע שׁוֹפָר, הַלְלוּהוּ בְּנֵבֶל וְכִנּוֹר: הַלְלוּהוּ בְתֹף וּמָחוֹל, הַלְלוּהוּ בְּמִנִּים וְעוּגָב: הַלְלוּהוּ בְצִלְצְלֵי שָׁמַע, הַלְלוּהוּ בְּצִלְצְלֵי תְרוּעָה: כֹּל הַנְּשָׁמָה תְּהַלֵּל יָהּ, הַלְלוּיָהּ: כֹּל הַנְּשָׁמָה תְּהַלֵּל יָהּ, הַלְלוּיָהּ:","cond":[]},{"kind":"text","text":"בָּרוּךְ יהוה לְעוֹלָם, אָמֵן וְאָמֵן: בָּרוּך יהוה מִצִּיּוֹן, שֹׁכֵן יְרוּשָׁלַיִם, הַלְלוּיָהּ: בָּרוּךְ יהוה אֱלֹהִים אֱלֹהֵי יִשְׂרָאֵל, עֹשֶׂה נִפְלָאוֹת לְבַדּוֹ: וּבָרוּךְ שֵׁם כְּבוֹדוֹ לְעוֹלָם, וְיִמָּלֵא כְבוֹדוֹ אֶת כָּל הָאָרֶץ, אָמֵן וְאָמֵן:","cond":[]},{"kind":"text","text":"וַיְבָרֶךְ דָּוִד אֶת יהוה לְעֵינֵי כָּל הַקָּהָל, וַיֹּאמֶר דָּוִד: בָּרוּךְ אַתָּה יהוה אֱלֹהֵי יִשְׂרָאֵל אָבִינוּ, מֵעוֹלָם וְעַד עוֹלָם: לְךָ יהוה הַגְּדֻלָּה, וְהַגְּבוּרָה, וְהַתִּפְאֶרֶת וְהַנֵּצַח וְהַהוֹד, כִּי כָל בַּשָּׁמַיִם וּבָאָרֶץ, לְךָ יהוה הַמַּמְלָכָה וְהַמִּתְנַשֵּׂא לְכָל לְרֹאשׁ: וְהָעֹשֶׁר וְהַכָּבוֹד מִלְּפָנֶיךָ, וְאַתָּה מוֹשֵׁל בַּכֹּל, וּבְיָדְךָ כֹּחַ וּגְבוּרָה וּבְיָדְךָ לְגַדֵּל וּלְחַזֵּק לַכֹּל: וְעַתָּה אֱלֹהֵינוּ מוֹדִים אֲנַחְנוּ לָךְ, וּמְהַלְלִים לְשֵׁם תִפְאַרְתֶּךְ: אַתָּה הוּא יהוה לְבַדֶּךָ, אַתָּה עָשִׂיתָ אֶת הַשָּׁמַיִם, שְׁמֵי הַשָּׁמַיִם וְכָל צְבָאָם, הָאָרֶץ וְכָל אֲשֶׁר עָלֶיהָ, הַיַּמִּים וְכָל אֲשֶׁר בָּהֶם, וְאַתָּה מְחַיֶּה אֶת כֻּלָּם, וּצְבָא הַשָּׁמַיִם לְךָ מִשְׁתַּחֲוִים: אַתָּה הוּא יהוה הָאֱלֹהִים אֲשֶׁר בָּחַרְתָּ בְּאַבְרָם וְהוֹצֵאתוֹ מֵאוּר כַּשְׂדִּים, וְשַׂמְתָּ שְׁמוֹ אַבְרָהָם: וּמָצָאתָ אֶת לְבָבוֹ נֶאֱמָן לְפָנֶיךָ, וְכָרוֹת עִמּוֹ הַבְּרִית לָתֵת אֶת אֶרֶץ הַכְּנַעֲנִי, הַחִתִּי, הָאֱמֹרִי וְהַפְּרִזִּי וְהַיְבוּסִי וְהַגִּרְגָּשִׁי לָתֵת לְזַרְעוֹ, וַתָּקֶם אֶת דְּבָרֶיךָ כִּי צַדִּיק אָתָּה: וַתֵּרֶא אֶת עֳנִי אֲבֹתֵינוּ בְּמִצְרָיִם, וְאֶת זַעֲקָתָם שָׁמַעְתָּ עַל יַם סוּף: וַתִּתֵּן אֹתֹת וּמֹפְתִים בְּפַרְעֹה וּבְכָל עֲבָדָיו וּבְכָל עַם אַרְצוֹ, כִּי יָדַעְתָּ כִּי הֵזִידוּ עֲלֵיהֶם, וַתַּעַשׂ לְךָ שֵׁם כְּהַיּוֹם הַזֶּה: וְהַיָּם בָּקַעְתָּ לִפְנֵיהֶם, וַיַּעַבְרוּ בְתוֹךְ הַיָּם בַּיַּבָּשָׁה, וְאֶת רֹדְפֵיהֶם הִשְׁלַכְתָּ בִמְצוֹלֹת כְּמוֹ אֶבֶן, בְּמַיִם עַזִּים:\n\nוַיּוֹשַׁע יהוה בַּיּוֹם הַהוּא אֶת יִשְׂרָאֵל מִיַּד מִצְרָיִם, וַיַּרְא יִשְׂרָאֵל אֶת מִצְרַיִם מֵת, עַל שְׂפַת הַיָּם: וַיַּרְא יִשְׂרָאֵל אֶת הַיָּד הַגְּדֹלָה אֲשֶׁר עָשָׂה יהוה בְּמִצְרַיִם, וַיִּירְאוּ הָעָם אֶת יהוה, וַיַּאֲמִינוּ בַּיהוה וּבְמֹשֶׁה עַבְדּוֹ:","cond":[]},{"kind":"header","text":"שירת הים","cond":[]},{"kind":"text","text":"אָז יָשִׁיר מֹשֶׁה וּבְנֵי יִשְׂרָאֵל אֶת הַשִּׁירָה הַזֹּאת לַיהוה וַיֹּאמְרוּ לֵּאמֹר, אָשִׁירָה לַיהוה כִּי גָאֹה גָּאָה, סוּס וְרֹכְבוֹ רָמָה בַיָּם: עָזִּי וְזִמְרָת יָהּ וַיְהִי לִי לִישׁוּעָה, זֶה אֵלִי וְאַנְוֵהוּ, אֱלֹהֵי אָבִי וַאֲרֹמְמֶנְהוּ: יהוה אִישׁ מִלְחָמָה, יהוה שְׁמוֹ: מַרְכְּבֹת פַּרְעֹה וְחֵילוֹ יָרָה בַיָּם, וּמִבְחַר שָׁלִשָׁיו טֻבְּעוּ בְיַם סוּף: תְּהֹמֹת יְכַסְיֻמוּ, יָרְדוּ בִמְצוֹלֹת כְּמוֹ אָבֶן: יְמִינְךָ יהוה נֶאְדָּרִי בַּכֹּחַ, יְמִינְךָ יהוה תִּרְעַץ אוֹיֵב: וּבְרֹב גְּאוֹנְךָ תַּהֲרֹס קָמֶיךָ, תְּשַׁלַּח חֲרֹנְךָ יֹאכְלֵמוֹ כַּקַּשׁ: וּבְרוּחַ אַפֶּיךָ נֶעֶרְמוּ מַיִם, נִצְּבוּ כְמוֹ נֵד נֹזְלִים, קָפְאוּ תְהֹמֹת בְּלֶב יָם: אָמַר אוֹיֵב אֶרְדֹּף אַשִּׂיג אֲחַלֵּק שָׁלָל, תִּמְלָאֵמוֹ נַפְשִׁי, אָרִיק חַרְבִּי, תּוֹרִישֵׁמוֹ יָדִי: נָשַׁפְתָּ בְרוּחֲךָ כִּסָּמוֹ יָם, צָלְלוּ כַּעוֹפֶרֶת בְּמַיִם, אַדִּירִים: מִי כָמֹכָה בָּאֵלִם יהוה, מִי כָּמֹכָה נֶאְדָּר בַּקֹּדֶשׁ, נוֹרָא תְהִלֹּת עֹשֵׂה פֶלֶא: נָטִיתָ יְמִינְךָ תִּבְלָעֵמוֹ אָרֶץ: נָחִיתָ בְחַסְדְּךָ עַם זוּ גָּאָלְתָּ, נֵהַלְתָּ בְעָזְּךָ אֶל נְוֵה קָדְשֶׁךָ: שָׁמְעוּ עַמִּים יִרְגָּזוּן, חִיל אָחַז יֹשְׁבֵי פְּלָשֶׁת: אָז נִבְהֲלוּ אַלּוּפֵי אֱדוֹם, אֵילֵי מוֹאָב יֹאחֲזֵמוֹ רָעַד, נָמֹגוּ כָּל יֹשְׁבֵי כְנָעַן: תִּפֹּל עֲלֵיהֶם אֵימָתָה וָפַחַד, בִּגְדֹל זְרוֹעֲךָ יִדְּמוּ כָּאָבֶן, עַד יַעֲבֹר עַמְּךָ, יהוה, עַד יַעֲבֹר עַם זוּ קָנִיתָ: תְּבִאֵמוֹ וְתִטָּעֵמוֹ בְּהַר נַחֲלָתְךָ, מָכוֹן לְשִׁבְתְּךָ פָּעַלְתָּ יהוה, מִקְּדָשׁ, אֲדֹנָי כּוֹנְנוּ יָדֶיךָ: יהוה יִמְלֹךְ לְעֹלָם וָעֶד: יהוה יִמְלֹךְ לְעֹלָם וָעֶד: יהוה מַלְכוּתֵהּ קָאֵם לְעָלַם וּלְעָלְמֵי עָלְמַיָּא. כִּי בָא סוּס פַּרְעֹה בְּרִכְבּוֹ וּבְפָרָשָׁיו בַּיָּם, וַיָּשֶׁב יהוה עֲלֵהֶם אֶת מֵי הַיָּם, וּבְנֵי יִשְׂרָאֵל הָלְכוּ בַיַּבָּשָׁה בְּתוֹךְ הַיָּם: כִּי לַיהוה הַמְּלוּכָה וּמֹשֵׁל בַּגּוֹיִם: וְעָלוּ מוֹשִׁעִים בְּהַר צִיּוֹן לִשְׁפֹּט אֶת הַר עֵשָׂו, וְהָיְתָה לַיהוה הַמְּלוּכָה: וְהָיָה יהוה לְמֶלֶךְ עַל כָּל הָאָרֶץ, בַּיּוֹם הַהוּא יִהְיֶה יהוה אֶחָד וּשְׁמוֹ אֶחָד:","cond":[]},{"kind":"text","text":"יִשְׁתַּבַּח שִׁמְךָ לָעַד, מַלְכֵּנוּ, הָאֵל הַמֶּלֶךְ הַגָּדוֹל וְהַקָּדוֹשׁ בַּשָּׁמַיִם וּבָאָרֶץ, כִּי לְךָ נָאֶה, יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ שִׁיר וּשְׁבָחָה, הַלֵּל וְזִמְרָה, עֹז וּמֶמְשָׁלָה, נֶצַח, גְּדֻלָּה וּגְבוּרָה, תְּהִלָּה וְתִפְאֶרֶת, קְדֻשָּׁה וּמַלְכוּת, בְּרָכוֹת וְהוֹדָאוֹת מֵעַתָּה וְעַד עוֹלָם. בָּרוּךְ אַתָּה יהוה, אֵל מֶלֶךְ גָּדוֹל בַּתִּשְׁבָּחוֹת, אֵל הַהוֹדָאוֹת, אֲדוֹן הַנִּפְלָאוֹת, הַבּוֹחֵר בְּשִׁירֵי זִמְרָה, מֶלֶךְ, אֵל, חֵי הָעוֹלָמִים.","cond":[]},{"kind":"header","text":"שיר המעלות","cond":["ayt"]},{"kind":"special","text":"שִׁיר הַמַּעֲלוֹת, מִמַּעֲמַקִּים קְרָאתִיךָ יהוה: אֲדֹנָי, שִׁמְעָה בְקוֹלִי, תִּהְיֶינָה אָזְנֶיךָ קַשֻּׁבוֹת לְקוֹל תַּחֲנוּנָי: אִם עֲוׂנוֹת תִּשְׁמָר יָהּ, אֲדֹנָי מִי יַעֲמֹד: כִּי עִמְּךָ הַסְּלִיחָה לְמַעַן תִּוָּרֵא: קִוִּיתִי יהוה, קִוְּתָה נַפְשִׁי, וְלִדְבָרוֹ הוֹחָלְתִּי: נַפְשִׁי לַאדֹנָי, מִשֹּׁמְרִים לַבֹּקֶר, שֹׁמְרִים לַבֹּקֶר: יַחֵל יִשְׂרָאֵל אֶל יהוה, כִּי עִם יהוה הַחֶסֶד וְהַרְבֵּה עִמּוֹ פְדוּת: וְהוּא יִפְדֶּה אֶת יִשְׂרָאֵל מִכֹּל עֲוֹנֹתָיו:","cond":["ayt"]},{"kind":"instruction","text":"חצי קדיש","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":[]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"header","text":"קריאת שמע וברכותיה","cond":[]},{"kind":"instruction","text":"קריאת שמע וברכותיה","cond":[]},{"kind":"instruction","text":"חזן:","cond":[]},{"kind":"text","text":"בָּרְכוּ אֶת יהוה הַמְבֹרָךְ.","cond":[]},{"kind":"instruction","text":"קהל וחזן:","cond":[]},{"kind":"text","text":"בָּרוּךְ יהוה הַמְבֹרָךְ לְעוֹלָם וָעֶד.","cond":[]},{"kind":"instruction","text":"הברכות שלפני קריאת שמע","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֵלֶךְ הָעוֹלָם, יוֹצֵר אוֹר וּבוֹרֵא חֹשֶׁךְ, עֹשֶׂה שָׁלוֹם וּבוֹרֵא אֶת הַכֹּל.\n\nהַמֵּאִיר לָאָרֶץ וְלַדָּרִים עָלֶיהָ בְּרַחֲמִים, וּבְטוּבוֹ מְחַדֵּשׁ בְּכָל יוֹם תָּמִיד מַעֲשֵׂה בְרֵאשִׁית. מָה רַבּוּ מַעֲשֶׂיךָ יהוה, כֻּלָם בְּחָכְמָה עָשִׂיתָ, מָלְאָה הָאָרֶץ קִנְיָנֶךָ: הַמֶּלֶךְ הַמְרוֹמָם לְבַדּוֹ מֵאָז, הַמְשֻׁבָּח וְהַמְפֹאָר וְהַמִּתְנַשֵּׂא מִימוֹת עוֹלָם. אֱלֹהֵי עוֹלָם, בְּרַחֲמֶיךָ הָרַבִּים רַחֵם עָלֵינוּ, אֲדוֹן עֻזֵּנוּ, צוּר מִשְׂגַּבֵּנוּ, מָגֵן יִשְׁעֵנוּ, מִשְׂגָּב בַּעֲדֵנוּ. אֵל בָּרוּךְ גְּדוֹל דֵּעָה, הֵכִין וּפָעַל זָהֳרֵי חַמָּה, טוֹב יָצַר כָּבוֹד לִשְׁמוֹ, מְאוֹרוֹת נָתַן סְבִיבוֹת עֻזּוֹ, פִּנּוֹת צְבָאָיו קְדוֹשִׁים, רוֹמְמֵי שַׁדַּי, תָּמִיד מְסַפְּרִים כְּבוֹד אֵל וּקְדֻשָּׁתוֹ. תִּתְבָּרַךְ יהוה אֱלֹהֵינוּ עַל שֶׁבַח מַעֲשֵׂה יָדֶיךָ וְעַל מְאוֹרֵי אוֹר שֶׁעָשִׂיתָ, יְפַאֲרוּךָ סֶּלָה. תִּתְבָּרַךְ צוּרֵנוּ מַלְכֵּנוּ וְגוֹאֲלֵנוּ בּוֹרֵא קְדוֹשִׁים, יִשְׁתַּבַּח שִׁמְךָ לָעַד מַלְכֵּנוּ יוֹצֵר מְשָׁרְתִים, וַאֲשֶׁר מְשָׁרְתָיו כֻּלָּם עוֹמְדִים בְּרוּם עוֹלָם וּמַשְׁמִיעִים בְּיִרְאָה יַחַד בְּקוֹל דִּבְרֵי אֱלֹהִים חַיִּים וּמֶלֶךְ עוֹלָם. כֻּלָּם אֲהוּבִים, כֻּלָּם בְּרוּרִים, כֻּלָּם גִּבּוֹרִים, וְכֻלָּם עוֹשִׂים בְּאֵימָה וּבְיִרְאָה רְצוֹן קוֹנָם, וְכֻלָּם פּוֹתְחִים אֶת פִּיהֶם בִּקְדֻשָּׁה וּבְטָהֳרָה, בְּשִׁירָה וּבְזִמְרָה, וּמְבָרְכִים וּמְשַׁבְּחִים וּמְפַאֲרִים וּמַעֲרִיצִים וּמַקְדִּישִׁים וּמַמְלִיכִים\n\nאֶת שֵׁם הָאֵל הַמֶּלֶךְ הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא, קָדוֹשׁ הוּא. וְכֻלָּם מְקַבְּלִים עֲלֵיהֶם עֹל מַלְכוּת שָׁמַיִם זֶה מִזֶּה, וְנוֹתְנִים רְשׁוּת זֶה לָזֶה לְהַקְדִּישׁ לְיוֹצְרָם בְּנַחַת רוּחַ, בְּשָׂפָה בְרוּרָה וּבִנְעִימָה, קְדֻשָּׁה כֻּלָּם כְּאֶחָד עוֹנִים וְאוֹמְרִים בְּיִרְאָה:\n\nקָדוֹשׁ, קָדוֹשׁ, קָדוֹשׁ יהוה צְבָאוֹת, מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ:\n\nוְהָאוֹפַנִּים וְחַיּוֹת הַקֹּדֶשׁ בְּרַעַשׁ גָּדוֹל מִתְנַשְּׂאִים לְעֻמַּת שְׂרָפִים, לְעֻמָּתָם מְשַׁבְּחִים וְאוֹמְרִים:\n\nבָּרוּךְ כְּבוֹד יהוה מִמְּקוֹמוֹ:\n\nלְאֵל בָּרוּךְ נְעִימוֹת יִתֵּנוּ, לְמֶלֶךְ אֵל חַי וְקַיָּם זְמִירוֹת יֹאמֵרוּ וְתִשְׁבָּחוֹת יַשְׁמִיעוּ, כִּי הוּא לְבַדּוֹ פּוֹעֵל גְּבוּרוֹת, עוֹשֶׂה חֲדָשׁוֹת, בַּעַל מִלְחָמוֹת, זוֹרֵעַ צְדָקוֹת, מַצְמִיחַ יְשׁוּעוֹת, בּוֹרֵא רְפוּאוֹת, נוֹרָא תְהִלּוֹת, אֲדוֹן הַנִּפְלָאוֹת, הַמְחַדֵּשׁ בְּטוּבוֹ בְּכָל יוֹם תָּמִיד מַעֲשֵׂה בְרֵאשִׁית, כָּאָמוּר: לְעֹשֵׂה אוֹרִים גְּדֹלִים, כִּי לְעוֹלָם חַסְדּוֹ: אוֹר חָדָשׁ עַל צִיּוֹן תָּאִיר וְנִזְכֶּה כֻלָּנוּ מְהֵרָה לְאוֹרוֹ. בָּרוּךְ אַתָּה יהוה, יוֹצֵר הַמְּאוֹרוֹת.\n\n\nאַהֲבָה רַבָּה אֲהַבְתָּנוּ, יהוה אֱלֹהֵינוּ, חֶמְלָה גְּדוֹלָה וִיתֵרָה חָמַלְתָּ עָלֵינוּ. אָבִינוּ מַלְכֵּנוּ, בַּעֲבוּר אֲבוֹתֵינוּ שֶׁבָּטְחוּ בְךָ, וַתְּלַמְּדֵם חֻקֵּי חַיִּים, כֵּן תְּחָנֵּנוּ וּתְלַמְּדֵנוּ. אָבִינוּ הָאָב הָרַחֲמָן, הַמְרַחֵם, רַחֵם עָלֵינוּ, וְתֵן בְּלִבֵּנוּ לְהָבִין וּלְהַשְׂכִּיל, לִשְׁמֹעַ, לִלְמֹד וּלְלַמֵּד, לִשְׁמֹר וְלַעֲשׂוֹת וּלְקַיֵּם אֶת כָּל דִּבְרֵי תַלְמוּד תּוֹרָתֶךָ בְּאַהֲבָה. וְהָאֵר עֵינֵינוּ בְּתוֹרָתֶךָ, וְדַבֵּק לִבֵּנוּ בְּמִצְוׂתֶיךָ, וְיַחֵד לְבָבֵנוּ לְאַהֲבָה וּלְיִרְאָה אֶת שְׁמֶךָ, וְלֹא נֵבוֹשׁ לְעוֹלָם וָעֶד. כִּי בְשֵׁם קָדְשְׁךָ הַגָּדוֹל וְהַנּוֹרָא בָּטָחְנוּ, נָגִילָה וְנִשְׂמְחָה בִּישׁוּעָתֶךָ. וַהֲבִיאֵנוּ לְשָׁלוֹם מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ, וְתוֹלִיכֵנוּ קוֹמְמִיּוּת לְאַרְצֵנוּ. כִּי אֵל פּוֹעֵל יְשׁוּעוֹת אָתָּה, וּבָנוּ בָחַרְתָּ מִכָּל עַם וְלָשׁוֹן, וְקֵרַבְתָּנוּ לְשִׁמְךָ הַגָּדוֹל סֶלָה בֶּאֱמֶת לְהוֹדוֹת לְךָ וּלְיַחֶדְךָ בְּאַהֲבָה. בָּרוּךְ אַתָּה יהוה, הַבּוֹחֵר בְּעַמּוֹ יִשְׂרָאֵל בְּאַהֲבָה.","cond":[]},{"kind":"header","text":"קריאת שמע","cond":[]},{"kind":"instruction","text":"קריאת שמע\n\nיחיד אומר:","cond":[]},{"kind":"text","text":"אֵל מֶלֶךְ נֶאֱמָן.","cond":[]},{"kind":"text","text":"שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:","cond":[]},{"kind":"instruction","text":"בלחש:","cond":[]},{"kind":"text","text":"בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד.\n\nוְאָהַבְתָּ אֵת יהוה אֱלֹהֶיךָ, בְּכָל לְבָבְךָ וּבְכָל נַפְשְׁךָ וּבְכָל מְאֹדֶךָ: וְהָיוּ הַדְּבָרִים הָאֵלֶּה אֲשֶׁר אָנֹכִי מְצַוְּךָ הַיּוֹם, עַל לְבָבֶךָ: וְשִׁנַּנְתָּם לְבָנֶיךָ וְדִבַּרְתָּ בָּם, בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ: וּקְשַׁרְתָּם לְאוֹת עַל יָדֶךָ, וְהָיוּ לְטֹטָפֹת בֵּין עֵינֶיךָ: וּכְתַבְתָּם עַל מְזֻזוֹת בֵּיתֶךָ וּבִשְׁעָרֶיךָ:","cond":[]},{"kind":"text","text":"וְהָיָה אִם שָׁמֹעַ תִּשְׁמְעוּ אֶל מִצְוׂתַי, אֲשֶׁר אָנֹכִי מְצַוֶּה אֶתְכֶם הַיּוֹם, לְאַהֲבָה אֶת יהוה אֱלֹהֵיכֶם וּלְעָבְדוֹ, בְּכָל לְבַבְכֶם וּבְכָל נַפְשְׁכֶם: וְנָתַתִּי מְטַר אַרְצְכֶם בְּעִתּוֹ, יוֹרֶה וּמַלְקוֹשׁ, וְאָסַפְתָּ דְגָנֶךָ וְתִירֹשְׁךָ וְיִצְהָרֶךָ: וְנָתַתִּי עֵשֶׂב בְּשָׂדְךָ לִבְהֶמְתֶּךָ, וְאָכַלְתָּ וְשָׂבָעְתָּ: הִשָּׁמְרוּ לָכֶם פֶּן יִפְתֶּה לְבַבְכֶם, וְסַרְתֶּם וַעֲבַדְתֶּם אֱלֹהִים אֲחֵרִים וְהִשְׁתַּחֲוִיתֶם לָהֶם: וְחָרָה אַף יהוה בָּכֶם, וְעָצַר אֶת הַשָּׁמַיִם וְלֹא יִהְיֶה מָטָר, וְהָאֲדָמָה לֹא תִתֵּן אֶת יְבוּלָהּ, וַאֲבַדְתֶּם מְהֵרָה מֵעַל הָאָרֶץ הַטֹּבָה אֲשֶׁר יהוה נֹתֵן לָכֶם: וְשַׂמְתֶּם אֶת דְּבָרַי אֵלֶּה עַל לְבַבְכֶם וְעַל נַפְשְׁכֶם, וּקְשַׁרְתֶּם אֹתָם לְאוֹת עַל יֶדְכֶם וְהָיוּ לְטוֹטָפֹת בֵּין עֵינֵיכֶם: וְלִמַּדְתֶּם אֹתָם אֶת בְּנֵיכֶם לְדַבֵּר בָּם, בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ: וּכְתַבְתָּם עַל מְזוּזוֹת בֵּיתֶךָ וּבִשְׁעָרֶיךָ: לְמַעַן יִרְבּוּ יְמֵיכֶם וִימֵי בְנֵיכֶם עַל הָאֲדָמָה אֲשֶׁר נִשְׁבַּע יהוה לַאֲבֹתֵיכֶם לָתֵת לָהֶם, כִּימֵי הַשָּׁמַיִם עַל הָאָרֶץ:","cond":[]},{"kind":"text","text":"וַיֹּאמֶר יהוה אֶל מֹשֶׁה לֵּאמֹר: דַּבֵּר אֶל בְּנֵי יִשְׂרָאֵל וְאָמַרְתָּ אֲלֵהֶם, וְעָשׂוּ לָהֶם צִיצִת עַל כַּנְפֵי בִגְדֵיהֶם לְדֹרֹתָם, וְנָתְנוּ עַל צִיצִת הַכָּנָף פְּתִיל תְּכֵלֶת: וְהָיָה לָכֶם לְצִיצִת, וּרְאִיתֶם אֹתוֹ, וּזְכַרְתֶּם אֶת כָּל מִצְוׂת יהוה וַעֲשִׂיתֶם אֹתָם, וְלֹא תָתֻרוּ אַחֲרֵי לְבַבְכֶם וְאַחֲרֵי עֵינֵיכֶם אֲשֶׁר אַתֶּם זֹנִים אַחֲרֵיהֶם: לְמַעַן תִּזְכְּרוּ וַעֲשִׂיתֶם אֶת כָּל מִצְוׂתָי, וִהְיִיתֶם קְדֹשִׁים לֵאלֹהֵיכֶם: אֲנִי יהוה אֱלֹהֵיכֶם אֲשֶׁר הוֹצֵאתִי אֶתְכֶם מֵאֶרֶץ מִצְרַיִם, לִהְיוֹת לָכֶם לֵאלֹהִים, אֲנִי יהוה אֱלֹהֵיכֶם:","cond":[]},{"kind":"text","text":"אֱמֶת","cond":[]},{"kind":"instruction","text":"הש\"ץ חוזר ואומר:","cond":[]},{"kind":"text","text":"יהוה אֱלֹהֵיכֶם: אֱמֶת","cond":[]},{"kind":"instruction","text":"הברכה שאחרי קריאת שמע","cond":[]},{"kind":"text","text":"וְיַצִּיב, וְנָכוֹן, וְקַיָּם, וְיָשָׁר, וְנֶאֱמָן, וְאָהוּב, וְחָבִיב, וְנֶחְמָד, וְנָעִים, וְנוֹרָא, וְאַדִּיר, וּמְתֻקָּן, וּמְקֻבָּל, וְטוֹב, וְיָפֶה, הַדָּבָר הַזֶּה עָלֵינוּ לְעוֹלָם וָעֶד.\n\nאֱמֶת, אֱלֹהֵי עוֹלָם מַלְכֵּנוּ, צוּר יַעֲקֹב מָגֵן יִשְׁעֵנוּ, לְדוֹר וָדוֹר הוּא קַיָּם, וּשְׁמוֹ קַיָּם, וְכִסְאוֹ נָכוֹן, וּמַלְכוּתו וֶאֱמוּנָתו לָעַד קַיֶּמֶת, וּדְבָרָיו חַיִּים וְקַיָּמִים, נֶאֱמָנִים וְנֶחֱמָדִים לָעַד וּלְעוֹלְמֵי עוֹלָמִים, עַל אֲבוֹתֵינוּ וְעָלֵינוּ, עַל בָּנֵינוּ וְעַל דּוֹרוֹתֵינוּ, וְעַל כָּל דּוֹרוֹת זֶרַע יִשְׂרָאֵל עֲבָדֶיךָ, עַל הָרִאשׁוֹנִים וְעַל הָאַחֲרוֹנִים דָּבָר טוֹב וְקַיָּם לְעוֹלָם וָעֶד, אֱמֶת וֶאֱמוּנָה חֹק וְלֹא יַעֲבוֹר. אֱמֶת שָׁאַתָּה הוּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מַלְכֵּנוּ מֶלֶךְ אֲבוֹתֵינוּ, גּוֹאֲלֵנוּ גּוֹאֵל אֲבוֹתֵינוּ, יוֹצְרֵנוּ צוּר יְשׁוּעָתֵנוּ, פּוֹדֵנוּ וּמַצִּילֵנוּ מֵעוֹלָם שְׁמֶךָ, אֵין אֱלֹהִים זוּלָתֶךָ.\n\nעֶזְרַת אֲבוֹתֵינוּ אַתָּה הוּא מֵעוֹלָם, מָגֵן וּמוֹשִׁיעַ לִבְנֵיהֶם אַחֲרֵיהֶם בְּכָל דּוֹר וָדוֹר, בְּרוּם עוֹלָם מוֹשָׁבֶךָ, וּמִשְׁפָּטֶיךָ, וְצִדְקָתְךָ עַד אַפְסֵי אָרֶץ. אַשְׁרֵי אִישׁ שֶׁיִּשְׁמַע לְמִצְוׂתֶיךָ, וְתוֹרָתְךָ וּדְבָרְךָ יָשִׂים עַל לִבּוֹ. אֱמֶת, אַתָּה הוּא אֲדוֹן לְעַמֶּךָ וּמֶלֶךְ גִּבּוֹר לָרִיב רִיבָם. אֱמֶת, אַתָּה הוּא רִאשׁוֹן, וְאַתָּה הוּא אַחֲרוֹן, וּמִבַּלְעָדֶיךָ אֵין לָנוּ מֶלֶךְ גּוֹאֵל וּמוֹשִׁיעַ. מִמִּצְרַיִם גְּאַלְתָּנוּ יהוה אֱלֹהֵינוּ, וּמִבֵּית עֲבָדִים פְּדִיתָנוּ, כָּל בְּכוֹרֵיהֶם הָרַגְתָּ, וּבְכוֹרְךָ גָּאַלְתָּ, וְיַם סוּף בָּקַעְתָּ, וְזֵדִים טִבַּעְתָּ, וִידִידִים הֶעֱבַרְתָּ, וַיְכַסּוּ מַיִם צָרֵיהֶם, אֶחָד מֵהֶם לֹא נוֹתַר. עַל זֹאת שִׁבְּחוּ אֲהוּבִים, וְרוֹמְמוּ אֵל, וְנָתְנוּ יְדִידִים זְמִירוֹת שִׁירוֹת וְתִשְׁבָּחוֹת בְּרָכוֹת וְהוֹדָאוֹת לְמֶלֶךְ אֵל חַי וְקַיָּם, רָם וְנִשָּׂא, גָּדוֹל וְנוֹרָא, מַשְׁפִּיל גֵּאִים וּמַגְבִּיהַּ שְׁפָלִים, מוֹצִיא אֲסִירִים וּפוֹדֶה עֲנָוִים, וְעוֹזֵר דַּלִּים, וְעוֹנֶה לְעַמּוֹ בְּעֵת שַׁוְּעָם אֵלָיו. תְּהִלּוֹת לְאֵל עֶלְיוֹן, בָּרוּךְ הוּא וּמְבֹרָךְ, מֹשֶׁה וּבְנֵי יִשְׂרָאֵל לְךָ עָנוּ שִׁירָה, בְּשִׂמְחָה רַבָּה, וְאָמְרוּ כֻלָּם:\n\nמִי כָמֹכָה בָּאֵלִם יהוה, מִי כָּמֹכָה נֶאְדָּר בַּקֹּדֶשׁ, נוֹרָא תְהִלֹּת עֹשֵׂה פֶלֶא:\n\nשִׁירָה חֲדָשָׁה שִׁבְּחוּ גְאוּלִים לְשִׁמְךָ עַל שְׂפַת הַיָּם, יַחַד כֻּלָּם הוֹדוּ וְהִמְלִיכוּ וְאָמְרוּ:\n\nיהוה יִמְלֹךְ לְעֹלָם וָעֶד:\n\nצוּר יִשְׂרָאֵל, קוּמָה בְּעֶזְרַת יִשְׂרָאֵל, וּפְדֵה כִנְאֻמֶּךָ יְהוּדָה וְיִשְׂרָאֵל. גֹּאֲלֵנוּ יהוה צְבָאוֹת שְׁמוֹ, קְדוֹשׁ יִשְׂרָאֵל: בָּרוּךְ אַתָּה יהוה, גָּאַל יִשְׂרָאֵל.","cond":[]},{"kind":"header","text":"עמידה","cond":[]},{"kind":"instruction","text":"תפילת העמידה","cond":[]},{"kind":"text","text":"אֲדֹנָי, שְׂפָתַי תִּפְתָּח, וּפִי יַגִּיד תְּהִלָּתֶךָ:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק, וֵאלֹהֵי יַעֲקֹב, הָאֵל הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, וְקוֹנֵה הַכֹּל, וְזוֹכֵר חַסְדֵי אָבוֹת, וּמֵבִיא גוֹאֵל לִבְנֵי בְנֵיהֶם לְמַעַן שְׁמוֹ בְּאַהֲבָה.","cond":[]},{"kind":"special","text":"זָכְרֵנוּ לְחַיִּים, מֶלֶךְ חָפֵץ בַּחַיִּים, וְכָתְבֵנוּ בְּסֵפֶר הַחַיִּים, לְמַעַנְךָ אֱלֹהִים חַיִּים.","cond":["ayt"]},{"kind":"text","text":"מֶלֶךְ עוֹזֵר וּמוֹשִׁיעַ וּמָגֵן. בָּרוּךְ אַתָּה יהוה, מָגֵן אַבְרָהָם.","cond":[]},{"kind":"text","text":"אַתָּה גִּבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֵּה מֵתִים אַתָּה רַב לְהוֹשִׁיעַ,","cond":[]},{"kind":"summer","text":"מוֹרִיד הַטָּל,","cond":["summerTal"]},{"kind":"winter","text":"מַשִּׁיב הָרוּחַ וּמוֹרִיד הַגֶּשֶׁם,","cond":["winterTal"]},{"kind":"text","text":"מְכַלְכֵּל חַיִּים בְּחֶסֶד, מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים, סוֹמֵךְ נוֹפְלִים, וְרוֹפֵא חוֹלִים וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמוּנָתוֹ לִישֵׁנֵי עָפָר. מִי כָמוֹךָ בַּעַל גְּבוּרוֹת וּמִי דּוֹמֶה לָךְ, מֶלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִיחַ יְשׁוּעָה.","cond":[]},{"kind":"special","text":"מִי כָמוֹךָ אַב הָרַחֲמִים, זוֹכֵר יְצוּרָיו לְחַיִּים בְּרַחֲמִים.","cond":["ayt"]},{"kind":"text","text":"וְנֶאֱמָן אַתָּה לְהַחֲיוֹת מֵתִים. בָּרוּךְ אַתָּה יהוה, מְחַיֵּה הַמֵּתִים.","cond":[]},{"kind":"text","text":"אַתָּה קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ וּקְדוֹשִׁים בְּכָל יוֹם יְהַלְלוּךָ סֶּלָה.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הָאֵל הַקָּדוֹשׁ.","cond":["noayt"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יהוה, הַמֶּלֶךְ הַקָּדוֹשׁ.","cond":["ayt"]},{"kind":"text","text":"אַתָּה חוֹנֵן לְאָדָם דַּעַת וּמְלַמֵּד לֶאֱנוֹשׁ בִּינָה.","cond":[]},{"kind":"text","text":"חָנֵּנוּ מֵאִתְּךָ דֵעָה בִּינָה וְהַשְׂכֵּל.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, חוֹנֵן הַדָּעַת.","cond":[]},{"kind":"text","text":"הֲשִׁיבֵנוּ אָבִינוּ לְתוֹרָתֶךָ, וְקָרְבֵנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶך, וְהַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ. בָּרוּךְ אַתָּה יהוה, הָרוֹצֶה בִּתְשׁוּבָה.","cond":[]},{"kind":"text","text":"סְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ, כִּי מוֹחֵל וְסוֹלֵחַ אָתָּה. בָּרוּךְ אַתָּה יהוה, חַנּוּן הַמַּרְבֶּה לִסְלֹחַ.","cond":[]},{"kind":"text","text":"רְאֵה בְעָנְיֵנוּ וְרִיבָה רִיבֵנוּ, וּגְאָלֵנוּ מְהֵרָה לְמַעַן שְׁמֶךָ, כִּי גוֹאֵל חָזָק אָתָּה. בָּרוּךְ אַתָּה יהוה, גּוֹאֵל יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"רְפָאֵנוּ יהוה וְנֵרָפֵא, הוֹשִׁיעֵנוּ וְנִוָּשֵׁעָה כִּי תְהִלָּתֵנוּ אָתָּה, וְהַעֲלֵה רְפוּאָה שְׁלֵמָה לְכָל מַכּוֹתֵינוּ.","cond":[]},{"kind":"special","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁתִּשְׁלַח מְהֵרָה רְפוּאָה שְׁלֵמָה מִן הַשָּׁמַיִם, רְפוּאַת הַנֶּפֶשׁ וּרְפוּאַת הַגּוּף לַחוֹלֶה (לנקבה: לַחוֹלָה, לרבים: לַחוֹלִים, לרבות: לַחוֹלוֹת):\n:=:=\nבְּתוֹךְ שְׁאָר חוֹלֵי יִשְׂרָאֵל.","cond":["doctor"]},{"kind":"text","text":"כִּי אֵל מֶלֶךְ רוֹפֵא נֶאֱמָן וְרַחֲמָן אָתָּה. בָּרוּךְ אַתָּה יהוה, רוֹפֵא חוֹלֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"בָּרֵך עָלֵינוּ יהוה אֱלֹהֵינוּ אֶת הַשָּׁנָה הַזֹּאת וְאֶת כָּל מִינֵי תְבוּאָתָהּ לְטוֹבָה, וְתֵן","cond":[]},{"kind":"summer","text":"בְּרָכָה","cond":["summerBracha"]},{"kind":"winter","text":"טַל וּמָטָר לִבְרָכָה","cond":["winterBracha"]},{"kind":"text","text":"עַל פְּנֵי הָאֲדָמָה וְשַׂבְּעֵנוּ מִטּוּבָהּ, וּבָרֵךְ שְׁנָתֵנוּ כַּשָּׁנִים הַטּוֹבוֹת. בָּרוּךְ אַתָּה יהוה, מְבָרֵךְ הַשָּׁנִים.","cond":[]},{"kind":"text","text":"תְּקַע בְּשׁוֹפָר גָּדוֹל לְחֵרוּתֵנוּ, וְשָׂא נֵס לְקַבֵּץ גָּלֻיּוֹתֵינוּ, וְקַבְּצֵנוּ יַחַד מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ. בָּרוּךְ אַתָּה יהוה, מְקַבֵּץ נִדְחֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"הָשִׁיבָה שׁוֹפְטֵינוּ כְּבָרִאשׁוֹנָה וְיוֹעֲצֵינוּ כְּבַתְּחִלָּה, וְהָסֵר מִמֶּנּוּ יָגוֹן וַאֲנָחָה, וּמְלֹךְ עָלֵינוּ אַתָּה יהוה לְבַדְּךָ בְּחֶסֶד וּבְרַחֲמִים, וְצַדְּקֵנוּ בַּמִּשְׁפָט.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, מֶלֶךְ אוֹהֵב צְדָקָה וּמִשְׁפָּט.","cond":["noayt"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יהוה, הַמֶּלֶךְ הַמִּשְׁפָּט.","cond":["ayt"]},{"kind":"text","text":"וְלַמַּלְשִׁינִים אַל תְּהִי תִקְוָה, וְכָל הָרִשְׁעָה כְּרֶגַע תֹּאבֵד, וְכָל אוֹיְבֵי עַמְּךָ מְהֵרָה יִכָּרֵתוּ, וְהַזֵּדִים מְהֵרָה תְעַקֵּר וּתְשַׁבֵּר וּתְמַגֵּר וְתַכְנִיעַ בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יהוה, שׁוֹבֵר אוֹיְבִים וּמַכְנִיעַ זֵדִים.","cond":[]},{"kind":"text","text":"עַל הַצַּדִּיקִים וְעַל הַחֲסִידִים, וְעַל זִקְנֵי עַמְּךָ בֵּית יִשְׂרָאֵל, וְעַל פְּלֵיטַת סוֹפרֵיהֶם, וְעַל גֵּרֵי הַצֶּדֶק וְעָלֵינוּ, יֶהֱמוּ רַחֲמֶיךָ יהוה אֱלֹהֵינוּ, וְתֵן שָׂכָר טוֹב לְכָל הַבּוֹטְחִים בְּשִׁמְךָ בֶּאֱמֶת, וְשִׂים חֶלְקֵנוּ עִמָּהֶם לְעוֹלָם וְלֹא נֵבוֹשׁ כִּי בְךָ בָטָחְנוּ. בָּרוּךְ אַתָּה יהוה, מִשְׁעָן וּמִבְטָח לַצַּדִּיקִים.","cond":[]},{"kind":"text","text":"וְלִירוּשָׁלַיִם עִירְךָ בְּרַחֲמִים תָּשׁוּב וְתִשְׁכֹּן בְּתוֹכָהּ כַּאֲשֶׁר דִּבַּרְתָּ, וּבְנֵה אוֹתָהּ בְּקָרוֹב בְּיָמֵינוּ בִּנְיָן עוֹלָם, וְכִסֵּא דָוִד מְהֵרָה לְתוֹכָהּ תָּכִין. בָּרוּךְ אַתָּה יהוה, בּוֹנֵה יְרוּשָׁלָיִם.","cond":[]},{"kind":"text","text":"אֶת צֶמַח דָּוִד עַבְדְּךָ מְהֵרָה תַצְמִיחַ, וְקַרְנוֹ תָּרוּם בִּישׁוּעָתֶךָ, כִּי לִישׁוּעָתְךָ קִוִּינוּ כָּל הַיּוֹם. בָּרוּךְ אַתָּה יהוה, מַצְמִיחַ קֶרֶן יְשׁוּעָה.","cond":[]},{"kind":"text","text":"שְׁמַע קוֹלֵנוּ יהוה אֱלֹהֵינוּ, חוּס וְרַחֵם עָלֵינוּ, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ, כִּי אֵל שׁוֹמֵעַ תְּפִלּוֹת וְתַחֲנוּנִים אָתָּה, וּמִלְּפָנֶיךָ מַלְכֵּנוּ, רֵיקָם אַל תְּשִׁיבֵנוּ.","cond":[]},{"kind":"special","text":"וַעֲנֵנוּ בּוֹרֵא עוֹלָם בְּמִדַּת הָרַחֲמִים, בּוֹחֵר בְּעַמּוֹ יִשְׂרָאֵל לְהוֹדִיעַ גָדְלוֹ וְהַדְרַת כְּבוֹדוֹ, שׁוֹמֵעַ תְּפִלָּה תֵּן טַל וּמָטָר עַל פְּנֵי הָאֲדָמָה, וְתַשְׂבִּיעַ אֶת הָעוֹלָם כֻּלּוֹ מִטּוּבֶךָ, וּמַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ וּמֵעֹשֶׁר מַתְּנַת יָדֶךָ, שְׁמוֹר וְהַצֵּל שָׁנָה זוֹ מִכָּל דָּבָר רָע, וּמִכָּל מִינִי מַשְׁחִית, וּמִכָּל מִינֵי פֻּרְעָנֻיּוֹת, וַעֲשֵׂה לָהּ תִּקְוָה וְאַחֲרִית שָׁלוֹם, חוּס וְרַחֵם עָלֵינוּ וְעַל כָּל תְּבוּאָתֵנוּ וּפֵרוֹתֵינוּ, וּבָרְכֵנוּ בְּגִשְׁמֵי בְרָכָה וְנִזְכֶּה לְחַיִּים וָשֹׂבַע וְשָׁלוֹם, כַּשָּׁנִים הַטּוֹבוֹת, וְהָסֵר מִמֶּנּוּ דֶּבֶר וְחֶרֶב וְרָעָב, וְחַיָּה רָעָה וּשְׁבִי וּבִזָּה, וְיֵצֶר הָרָע וָחֳלָיִם רָעִים וְקָשִׁים, וּמְאוֹרָעוֹת רָעִים וְקָשִׁים, וּגְזֹר עָלֵינוּ גְּזֵרוֹת טוֹבוֹת מִלְּפָנֶיךָ, וְיִגֹּלוּ רָחֲמֶיךָ עַל מִדּוֹתֶיךָ, וְתִתְנַהֵג עִם בָּנֶיךָ בְּמִדַּת הָרַחֲמִים, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ.","cond":["vaanenu"]},{"kind":"text","text":"כִּי אַתָּה שׁוֹמֵעַ תְּפִלַּת עַמְּךָ יִשְׂרָאֵל בְּרַחֲמִים. בָּרוּךְ אַתָּה יהוה, שׁוֹמֵעַ תְּפִלָּה.","cond":[]},{"kind":"text","text":"רְצֵה יהוה אֱלֹהֵינוּ בְּעַמְּךָ יִשְׂרָאֵל וּבִתְפִלָּתָם, וְהָשֵׁב אֶת הָעֲבוֹדָה לִדְבִיר בֵּיתֶךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם, בְּאַהֲבָה תְקַבֵּל בְּרָצוֹן. וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּךָ.","cond":[]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וּפִקְדוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךָ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים, לְחַיִּים וּלְשָׁלוֹם בְּיוֹם","cond":["rh"]},{"kind":"special","text":"רֹאשׁ הַחֹדֶשׁ הַזֶּה.","cond":["rh"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["rh"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וּפִקְדוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךָ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים, לְחַיִּים וּלְשָׁלוֹם בְּיוֹם","cond":["sucot"]},{"kind":"special","text":"חַג הַסֻּכּוֹת הַזֶּה.","cond":["sucot"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["sucot"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וּפִקְדוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךָ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים, לְחַיִּים וּלְשָׁלוֹם בְּיוֹם","cond":["pesach"]},{"kind":"special","text":"חַג הַמַּצּוֹת הַזֶּה.","cond":["pesach"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["pesach"]},{"kind":"text","text":"וְתֶחֱזֶינָה עֵינֵינוּ בְּשׁוּבְךָ לְצִיּוֹן בְּרַחֲמִים. בָּרוּךְ אַתָּה יהוה, הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן.","cond":[]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שָׁאַתָּה הוּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ לְעוֹלָם וָעֶד. צוּר חַיֵּינוּ, מָגֵן יִשְׁעֵנוּ אַתָּה הוּא לְדוֹר וָדוֹר. נוֹדֶה לְּךָ וּנְסַפֵּר תְּהִלָּתֶךָ עַל חַיֵּינוּ הַמְּסוּרִים בְּיָדֶךָ, וְעַל נִשְׁמוֹתֵינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּיךָ שֶׁבְּכָל יוֹם עִמָּנוּ, וְעַל נִפְלְאוֹתֶיךָ וְטוֹבוֹתֶיךָ שֶׁבְּכָל עֵת, עֶרֶב וָבֹקֶר וְצָהֳרָיִם. הַטּוֹב כִּי לֹא כָלוּ רַחֲמֶיךָ, וְהַמְרַחֵם כִּי לֹא תַמּוּ חֲסָדֶיךָ. מֵעוֹלָם קִוִּינוּ לָךְ.","cond":[]},{"kind":"special","text":"עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מַתִּתְיָהוּ בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְהַשְׁכִּיחָם תּוֹרָתֶךָ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנֶךָ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּטְמֵאִים בְּיַד טְהוֹרִים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, וּלְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמֶךָ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כֵּן בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ לְהוֹדוֹת וּלְהַלֵּל לְשִׁמְךָ הַגָּדוֹל.","cond":["chanuka"]},{"kind":"special","text":"עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים, מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ, וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ, וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְּרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ (, וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה).","cond":["purim"]},{"kind":"text","text":"וְעַל כֻּלָּם יִתְבָּרַךְ וְיִתְרוֹמַם שִׁמְךָ מַלְכֵּנוּ תָּמִיד לְעוֹלָם וָעֶד.","cond":[]},{"kind":"special","text":"וּכְתֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶךָ.","cond":["ayt"]},{"kind":"text","text":"וְכֹל הַחַיִּים יוֹדוּךָ סֶּלָה, וִיהַלְלוּ אֶת שִׁמְךָ בֶּאֱמֶת, הָאֵל יְשׁוּעָתֵנוּ וְעֶזְרָתֵנוּ סֶלָה. בָּרוּך אַתָּה יהוה, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת.","cond":[]},{"kind":"text","text":"שִׂים שָׁלוֹם טוֹבָה וּבְרָכָה, חֵן וָחֶסֶד וְרַחֲמִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל עַמֶּךָ, בָּרְכֵנוּ אָבִינוּ כֻּלָּנוּ כְּאֶחָד בְּאוֹר פָּנֶיךָ, כִּי בְאוֹר פָּנֶיךָ נָתַתָּ לָּנוּ יהוה אֱלֹהֵינוּ תּוֹרַת חַיִּים וְאַהֲבַת חֶסֶד, וּצְדָקָה וּבְרָכָה וְרַחֲמִים וְחַיִּים וְשָׁלוֹם, וְטוֹב בְּעֵינֶיךָ לְבָרֵךְ אֶת עַמְּךָ יִשְׂרָאֵל בְּכָל עֵת וּבְכָל שָׁעָה בִּשְׁלוֹמֶךָ.","cond":[]},{"kind":"special","text":"בְּסֵפֶר חַיִּים, בְּרָכָה וְשָׁלוֹם, וּפַרְנָסָה טוֹבָה, נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ, אֲנַחְנוּ וְכָל עַמְּךָ בֵּית יִשְׂרָאֵל, לְחַיִּים טוֹבִים וּלְשָׁלוֹם.","cond":["ayt"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הַמְבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם.","cond":[]},{"kind":"text","text":"יִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:\nאֱלֹהַי, נְצֹר לְשׁוֹנִי מֵרָע וּשְׂפָתַי מִדַּבֵּר מִרְמָה, וְלִמְקַלְלַי נַפְשִׁי תִדֹּם, וְנַפְשִׁי כֶּעָפָר לַכֹּל תִּהְיֶה. פְּתַח לִבִּי בְּתוֹרָתֶךָ, וּבְמִצְוׂתֶיךָ תִּרְדֹף נַפְשִׁי. וְכָל הַחוֹשְׁבִים עָלַי רָעָה, מְהֵרָה הָפֵר עֲצָתָם וְקַלְקֵל מַחֲשַׁבְתָּם. עֲשֵׂה לְמַעַן שְׁמֶךָ, עֲשֵׂה לְמַעַן יְמִינֶךָ, עֲשֵׂה לְמַעַן קְדֻשָּׁתֶךָ, עֲשֵׂה לְמַעַן תּוֹרָתֶךָ. לְמַעַן יֵחָלְצוּן יְדִידֶיךָ הוֹשִׁיעָה יְמִינְךָ וַעֲנֵנִי:\nיִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:","cond":[]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁיִּבָּנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵינוּ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתֶךָ, וְשָׁם נַעֲבָדְךָ בְּיִרְאָה כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמוֹנִיּוֹת. וְעָרְבָה לַיהוה מִנְחַת יְהוּדָה וִירוּשָׁלָיִם כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמֹנִיּוֹת:","cond":[]},{"kind":"header","text":"חזרת הש\"ץ","cond":[]},{"kind":"instruction","text":"חזרת הש\"ץ","cond":[]},{"kind":"text","text":"אֲדֹנָי, שְׂפָתַי תִּפְתָּח, וּפִי יַגִּיד תְּהִלָּתֶךָ:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק, וֵאלֹהֵי יַעֲקֹב, הָאֵל הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, וְקוֹנֵה הַכֹּל, וְזוֹכֵר חַסְדֵי אָבוֹת, וּמֵבִיא גוֹאֵל לִבְנֵי בְנֵיהֶם לְמַעַן שְׁמוֹ בְּאַהֲבָה.","cond":[]},{"kind":"special","text":"זָכְרֵנוּ לְחַיִּים, מֶלֶךְ חָפֵץ בַּחַיִּים, וְכָתְבֵנוּ בְּסֵפֶר הַחַיִּים, לְמַעַנְךָ אֱלֹהִים חַיִּים.","cond":["ayt"]},{"kind":"text","text":"מֶלֶךְ עוֹזֵר וּמוֹשִׁיעַ וּמָגֵן. בָּרוּךְ אַתָּה יהוה, מָגֵן אַבְרָהָם.","cond":[]},{"kind":"text","text":"אַתָּה גִּבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֵּה מֵתִים אַתָּה רַב לְהוֹשִׁיעַ,","cond":[]},{"kind":"summer","text":"מוֹרִיד הַטָּל,","cond":["summerTal"]},{"kind":"winter","text":"מַשִּׁיב הָרוּחַ וּמוֹרִיד הַגֶּשֶׁם,","cond":["winterTal"]},{"kind":"text","text":"מְכַלְכֵּל חַיִּים בְּחֶסֶד, מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים, סוֹמֵךְ נוֹפְלִים, וְרוֹפֵא חוֹלִים וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמוּנָתוֹ לִישֵׁנֵי עָפָר. מִי כָמוֹךָ בַּעַל גְּבוּרוֹת וּמִי דּוֹמֶה לָךְ, מֶלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִיחַ יְשׁוּעָה.","cond":[]},{"kind":"special","text":"מִי כָמוֹךָ אַב הָרַחֲמִים, זוֹכֵר יְצוּרָיו לְחַיִּים בְּרַחֲמִים.","cond":["ayt"]},{"kind":"text","text":"וְנֶאֱמָן אַתָּה לְהַחֲיוֹת מֵתִים. בָּרוּךְ אַתָּה יהוה, מְחַיֵּה הַמֵּתִים.","cond":[]},{"kind":"header","text":"קדושה","cond":[]},{"kind":"instruction","text":"קדושה בחזרת הש\"ץ:","cond":[]},{"kind":"text","text":"נְקַדֵּשׁ אֶת שִׁמְךָ בָּעוֹלָם כְּשֵׁם שֶׁמַּקְדִּישִׁים אוֹתוֹ בִּשְׁמֵי מָרוֹם, כַּכָּתוּב עַל יַד נְבִיאֶךָ:\nוְקָרָא זֶה אֶל זֶה וְאָמַר:\nקו\"ח: קָדוֹשׁ, קָדוֹשׁ, קָדוֹשׁ יהוה צְבָאוֹת, מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ:\nחזן: לְעֻמָּתָם בָּרוּךְ יֹאמֵרוּ:\nקו\"ח: בָּרוּךְ כְּבוֹד יהוה מִמְּקוֹמוֹ:\nחזן: וּבְדִבְרֵי קָדְשְׁךָ כָּתוּב לֵאמֹר:\nקו\"ח: יִמְלֹך יהוה לְעוֹלָם, אֱלֹהַיִך צִיּוֹן לְדֹר וָדֹר, הַלְלוּיָהּ:\n\nלְדוֹר וָדוֹר נַגִּיד גָּדְלֶךָ וּלְנֵצַח נְצָחִים קְדֻשָּׁתְךָ נַקְדִּישׁ, וְשִׁבְחֲךָ אֱלֹהֵינוּ מִפִּינוּ לֹא יָמוּשׁ לְעוֹלָם וָעֵד, כִּי אֵל מֶלֶךְ גָּדוֹל וְקָדוֹשׁ אָתָּה.","cond":[]},{"kind":"special","text":"בָּרוּךְ אַתָּה יהוה, הַמֶּלֶךְ הַקָּדוֹשׁ.","cond":["ayt"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הָאֵל הַקָּדוֹשׁ.","cond":["noayt"]},{"kind":"text","text":"אַתָּה חוֹנֵן לְאָדָם דַּעַת וּמְלַמֵּד לֶאֱנוֹשׁ בִּינָה.","cond":[]},{"kind":"text","text":"חָנֵּנוּ מֵאִתְּךָ דֵעָה בִּינָה וְהַשְׂכֵּל.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, חוֹנֵן הַדָּעַת.","cond":[]},{"kind":"text","text":"הֲשִׁיבֵנוּ אָבִינוּ לְתוֹרָתֶךָ, וְקָרְבֵנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶך, וְהַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ. בָּרוּךְ אַתָּה יהוה, הָרוֹצֶה בִּתְשׁוּבָה.","cond":[]},{"kind":"text","text":"סְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ, כִּי מוֹחֵל וְסוֹלֵחַ אָתָּה. בָּרוּךְ אַתָּה יהוה, חַנּוּן הַמַּרְבֶּה לִסְלֹחַ.","cond":[]},{"kind":"text","text":"רְאֵה בְעָנְיֵנוּ וְרִיבָה רִיבֵנוּ, וּגְאָלֵנוּ מְהֵרָה לְמַעַן שְׁמֶךָ, כִּי גוֹאֵל חָזָק אָתָּה. בָּרוּךְ אַתָּה יהוה, גּוֹאֵל יִשְׂרָאֵל.","cond":[]},{"kind":"instruction","text":"בתענית צבור החזן אומר:","cond":["taanit"]},{"kind":"special","text":"עֲנֵנוּ יהוה עֲנֵנוּ בְּיוֹם צוֹם תַּעֲנִיתֵנוּ, כִּי בְצָרָה גְדוֹלָה אֲנָחְנוּ. אַל תֵּפֶן אֶל רִשְׁעֵנוּ, וְאַל תַּסְתֵּר פָּנֶיךָ מִמֶּנּוּ, וְאַל תִּתְעַלַּם מִתְּחִנָּתֵנוּ. הֱיֵה נָא קָרוֹב לְשַׁוְעָתֵנוּ, יְהִי נָא חַסְדְּךָ לְנַחֲמֵנוּ, טֶרֶם נִקְרָא אֵלֶיךָ עֲנֵנוּ, כַּדָּבָר שֶׁנֶּאֱמַר: וְהָיָה טֶרֶם יִקְרָאוּ וַאֲנִי אֶעֱנֶה, עוֹד הֵם מְדַבְּרִים וַאֲנִי אֶשְׁמָע: כִּי אַתָּה יהוה הָעוֹנֶה בְּעֵת צָרָה, פּוֹדֶה וּמַצִּיל בְּכָל עֵת צָרָה וְצוּקָה. בָּרוּךְ אַתָּה יהוה, הָעוֹנֶה בְּעֵת צָרָה.","cond":["taanit"]},{"kind":"text","text":"רְפָאֵנוּ יהוה וְנֵרָפֵא, הוֹשִׁיעֵנוּ וְנִוָּשֵׁעָה כִּי תְהִלָּתֵנוּ אָתָּה, וְהַעֲלֵה רְפוּאָה שְׁלֵמָה לְכָל מַכּוֹתֵינוּ, כִּי אֵל מֶלֶךְ רוֹפֵא נֶאֱמָן וְרַחֲמָן אָתָּה. בָּרוּךְ אַתָּה יהוה, רוֹפֵא חוֹלֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"בָּרֵך עָלֵינוּ יהוה אֱלֹהֵינוּ אֶת הַשָּׁנָה הַזֹּאת וְאֶת כָּל מִינֵי תְבוּאָתָהּ לְטוֹבָה, וְתֵן","cond":[]},{"kind":"summer","text":"בְּרָכָה","cond":["summerBracha"]},{"kind":"winter","text":"טַל וּמָטָר לִבְרָכָה","cond":["winterBracha"]},{"kind":"text","text":"עַל פְּנֵי הָאֲדָמָה וְשַׂבְּעֵנוּ מִטּוּבָהּ, וּבָרֵךְ שְׁנָתֵנוּ כַּשָּׁנִים הַטּוֹבוֹת. בָּרוּךְ אַתָּה יהוה, מְבָרֵךְ הַשָּׁנִים.","cond":[]},{"kind":"text","text":"תְּקַע בְּשׁוֹפָר גָּדוֹל לְחֵרוּתֵנוּ, וְשָׂא נֵס לְקַבֵּץ גָּלֻיּוֹתֵינוּ, וְקַבְּצֵנוּ יַחַד מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ. בָּרוּךְ אַתָּה יהוה, מְקַבֵּץ נִדְחֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"הָשִׁיבָה שׁוֹפְטֵינוּ כְּבָרִאשׁוֹנָה וְיוֹעֲצֵינוּ כְּבַתְּחִלָּה, וְהָסֵר מִמֶּנּוּ יָגוֹן וַאֲנָחָה, וּמְלֹךְ עָלֵינוּ אַתָּה יהוה לְבַדְּךָ בְּחֶסֶד וּבְרַחֲמִים, וְצַדְּקֵנוּ בַּמִּשְׁפָט.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, מֶלֶךְ אוֹהֵב צְדָקָה וּמִשְׁפָּט.","cond":["noayt"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יהוה, הַמֶּלֶךְ הַמִּשְׁפָּט.","cond":["ayt"]},{"kind":"text","text":"וְלַמַּלְשִׁינִים אַל תְּהִי תִקְוָה, וְכָל הָרִשְׁעָה כְּרֶגַע תֹּאבֵד, וְכָל אוֹיְבֵי עַמְּךָ מְהֵרָה יִכָּרֵתוּ, וְהַזֵּדִים מְהֵרָה תְעַקֵּר וּתְשַׁבֵּר וּתְמַגֵּר וְתַכְנִיעַ בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יהוה, שׁוֹבֵר אוֹיְבִים וּמַכְנִיעַ זֵדִים.","cond":[]},{"kind":"text","text":"עַל הַצַּדִּיקִים וְעַל הַחֲסִידִים, וְעַל זִקְנֵי עַמְּךָ בֵּית יִשְׂרָאֵל, וְעַל פְּלֵיטַת סוֹפרֵיהֶם, וְעַל גֵּרֵי הַצֶּדֶק וְעָלֵינוּ, יֶהֱמוּ רַחֲמֶיךָ יהוה אֱלֹהֵינוּ, וְתֵן שָׂכָר טוֹב לְכָל הַבּוֹטְחִים בְּשִׁמְךָ בֶּאֱמֶת, וְשִׂים חֶלְקֵנוּ עִמָּהֶם לְעוֹלָם וְלֹא נֵבוֹשׁ כִּי בְךָ בָטָחְנוּ. בָּרוּךְ אַתָּה יהוה, מִשְׁעָן וּמִבְטָח לַצַּדִּיקִים.","cond":[]},{"kind":"text","text":"וְלִירוּשָׁלַיִם עִירְךָ בְּרַחֲמִים תָּשׁוּב וְתִשְׁכֹּן בְּתוֹכָהּ כַּאֲשֶׁר דִּבַּרְתָּ, וּבְנֵה אוֹתָהּ בְּקָרוֹב בְּיָמֵינוּ בִּנְיָן עוֹלָם, וְכִסֵּא דָוִד מְהֵרָה לְתוֹכָהּ תָּכִין. בָּרוּךְ אַתָּה יהוה, בּוֹנֵה יְרוּשָׁלָיִם.","cond":[]},{"kind":"text","text":"אֶת צֶמַח דָּוִד עַבְדְּךָ מְהֵרָה תַצְמִיחַ, וְקַרְנוֹ תָּרוּם בִּישׁוּעָתֶךָ, כִּי לִישׁוּעָתְךָ קִוִּינוּ כָּל הַיּוֹם. בָּרוּךְ אַתָּה יהוה, מַצְמִיחַ קֶרֶן יְשׁוּעָה.","cond":[]},{"kind":"text","text":"שְׁמַע קוֹלֵנוּ יהוה אֱלֹהֵינוּ, חוּס וְרַחֵם עָלֵינוּ, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ, כִּי אֵל שׁוֹמֵעַ תְּפִלּוֹת וְתַחֲנוּנִים אָתָּה, וּמִלְּפָנֶיךָ מַלְכֵּנוּ, רֵיקָם אַל תְּשִׁיבֵנוּ.","cond":[]},{"kind":"special","text":"וַעֲנֵנוּ בּוֹרֵא עוֹלָם בְּמִדַּת הָרַחֲמִים, בּוֹחֵר בְּעַמּוֹ יִשְׂרָאֵל לְהוֹדִיעַ גָדְלוֹ וְהַדְרַת כְּבוֹדוֹ, שׁוֹמֵעַ תְּפִלָּה תֵּן טַל וּמָטָר עַל פְּנֵי הָאֲדָמָה, וְתַשְׂבִּיעַ אֶת הָעוֹלָם כֻּלּוֹ מִטּוּבֶךָ, וּמַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ וּמֵעֹשֶׁר מַתְּנַת יָדֶךָ, שְׁמוֹר וְהַצֵּל שָׁנָה זוֹ מִכָּל דָּבָר רָע, וּמִכָּל מִינִי מַשְׁחִית, וּמִכָּל מִינֵי פֻּרְעָנֻיּוֹת, וַעֲשֵׂה לָהּ תִּקְוָה וְאַחֲרִית שָׁלוֹם, חוּס וְרַחֵם עָלֵינוּ וְעַל כָּל תְּבוּאָתֵנוּ וּפֵרוֹתֵינוּ, וּבָרְכֵנוּ בְּגִשְׁמֵי בְרָכָה וְנִזְכֶּה לְחַיִּים וָשֹׂבַע וְשָׁלוֹם, כַּשָּׁנִים הַטּוֹבוֹת, וְהָסֵר מִמֶּנּוּ דֶּבֶר וְחֶרֶב וְרָעָב, וְחַיָּה רָעָה וּשְׁבִי וּבִזָּה, וְיֵצֶר הָרָע וָחֳלָיִם רָעִים וְקָשִׁים, וּמְאוֹרָעוֹת רָעִים וְקָשִׁים, וּגְזֹר עָלֵינוּ גְּזֵרוֹת טוֹבוֹת מִלְּפָנֶיךָ, וְיִגֹּלוּ רָחֲמֶיךָ עַל מִדּוֹתֶיךָ, וְתִתְנַהֵג עִם בָּנֶיךָ בְּמִדַּת הָרַחֲמִים, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ.","cond":["vaanenu"]},{"kind":"text","text":"כִּי אַתָּה שׁוֹמֵעַ תְּפִלַּת עַמְּךָ יִשְׂרָאֵל בְּרַחֲמִים. בָּרוּךְ אַתָּה יהוה, שׁוֹמֵעַ תְּפִלָּה.","cond":[]},{"kind":"text","text":"רְצֵה יהוה אֱלֹהֵינוּ בְּעַמְּךָ יִשְׂרָאֵל וּבִתְפִלָּתָם, וְהָשֵׁב אֶת הָעֲבוֹדָה לִדְבִיר בֵּיתֶךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם, בְּאַהֲבָה תְקַבֵּל בְּרָצוֹן. וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּךָ.","cond":[]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וּפִקְדוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךָ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים, לְחַיִּים וּלְשָׁלוֹם בְּיוֹם","cond":["rh"]},{"kind":"special","text":"רֹאשׁ הַחֹדֶשׁ הַזֶּה.","cond":["rh"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["rh"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וּפִקְדוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךָ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים, לְחַיִּים וּלְשָׁלוֹם בְּיוֹם","cond":["sucot"]},{"kind":"special","text":"חַג הַסֻּכּוֹת הַזֶּה.","cond":["sucot"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["sucot"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וּפִקְדוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךָ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים, לְחַיִּים וּלְשָׁלוֹם בְּיוֹם","cond":["pesach"]},{"kind":"special","text":"חַג הַמַּצּוֹת הַזֶּה.","cond":["pesach"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["pesach"]},{"kind":"text","text":"וְתֶחֱזֶינָה עֵינֵינוּ בְּשׁוּבְךָ לְצִיּוֹן בְּרַחֲמִים. בָּרוּךְ אַתָּה יהוה, הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן.","cond":[]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שָׁאַתָּה הוּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ לְעוֹלָם וָעֶד. צוּר חַיֵּינוּ, מָגֵן יִשְׁעֵנוּ אַתָּה הוּא לְדוֹר וָדוֹר. נוֹדֶה לְּךָ וּנְסַפֵּר תְּהִלָּתֶךָ עַל חַיֵּינוּ הַמְּסוּרִים בְּיָדֶךָ, וְעַל נִשְׁמוֹתֵינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּיךָ שֶׁבְּכָל יוֹם עִמָּנוּ, וְעַל נִפְלְאוֹתֶיךָ וְטוֹבוֹתֶיךָ שֶׁבְּכָל עֵת, עֶרֶב וָבֹקֶר וְצָהֳרָיִם. הַטּוֹב כִּי לֹא כָלוּ רַחֲמֶיךָ, וְהַמְרַחֵם כִּי לֹא תַמּוּ חֲסָדֶיךָ. מֵעוֹלָם קִוִּינוּ לָךְ.","cond":[]},{"kind":"header","text":"מודים דרבנן","cond":[]},{"kind":"instruction","text":"מודים דרבנן:","cond":[]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שָׁאַתָּה הוּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי כָל בָּשָׂר, יוֹצְרֵנוּ יוֹצֵר בְּרֵאשִׁית. בְּרָכוֹת וְהוֹדָאוֹת לְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ, עַל שֶׁהֶחֱיִיתָנוּ וְקִיַּמְתָּנוּ. כֵּן תְּחַיֵּנוּ וּתְקַיְּמֵנוּ, וְתֶאֱסוֹף גָּלֻיּוֹתֵינוּ לְחַצְרוֹת קָדְשֶׁךָ, לִשְׁמוֹר חֻקֶּיךָ וְלַעֲשׂוֹת רְצוֹנֶךָ, וּלְעָבְדְּךָ בְּלֵבָב שָׁלֵם, עַל שֶׁאֲנַחְנוּ מוֹדִים לָךְ. בָּרוּךְ אֵל הַהוֹדָאוֹת.","cond":[]},{"kind":"special","text":"עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מַתִּתְיָהוּ בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְהַשְׁכִּיחָם תּוֹרָתֶךָ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנֶךָ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּטְמֵאִים בְּיַד טְהוֹרִים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, וּלְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמֶךָ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כֵּן בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ לְהוֹדוֹת וּלְהַלֵּל לְשִׁמְךָ הַגָּדוֹל.","cond":["chanuka"]},{"kind":"special","text":"עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים, מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ, וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ, וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְּרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ (, וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה).","cond":["purim"]},{"kind":"text","text":"וְעַל כֻּלָּם יִתְבָּרַךְ וְיִתְרוֹמַם שִׁמְךָ מַלְכֵּנוּ תָּמִיד לְעוֹלָם וָעֶד.","cond":[]},{"kind":"special","text":"וּכְתֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶךָ.","cond":["ayt"]},{"kind":"text","text":"וְכֹל הַחַיִּים יוֹדוּךָ סֶּלָה, וִיהַלְלוּ אֶת שִׁמְךָ בֶּאֱמֶת, הָאֵל יְשׁוּעָתֵנוּ וְעֶזְרָתֵנוּ סֶלָה. בָּרוּך אַתָּה יהוה, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת.","cond":[]},{"kind":"header","text":"ברכת כהנים","cond":["noTishaaBeav"]},{"kind":"instruction","text":"ברכת כהנים לחזרת הש\"ץ:\n\nאם לא עלו כהנים לדוכן הש\"ץ אומר או\"א (נמצא בהמשך).\n\nאם עלו שני כהנים לדוכן קוראים להם - כֹּהֲנִים:\n\nהכהנים מברכים:","cond":["noTishaaBeav"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בִּקְדֻשָּׁתוֹ שֶׁל אַהֲרֹן, וְצִוָּנוּ לְבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בְּאַהֲבָה.\n\nיְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ:\nיָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ:\nיִשָּׂא יהוה פָּנָיו אֵלֶיךָ וְיָשֵׂם לְךָ שָׁלוֹם:","cond":["noTishaaBeav"]},{"kind":"instruction","text":"הקהל אומר:","cond":["noTishaaBeav"]},{"kind":"text","text":"אַדִּיר בַּמָּרוֹם שׁוֹכֵן בִּגְבוּרָה, אַתָּה שָׁלוֹם וְשִׁמְךָ שָׁלוֹם. יְהִי רָצוֹן שֶׁתָּשִׂים עָלֵינוּ וְעַל כָּל עַמְּךָ בֵּית יִשְׂרָאֵל חַיִּים וּבְרָכָה לְמִשְׁמֶרֶת שָׁלוֹם.","cond":["noTishaaBeav"]},{"kind":"instruction","text":"הכהנים אומרים","cond":["noTishaaBeav"]},{"kind":"text","text":"רִבּוֹנוֹ שֶׁל עוֹלָם, עָשִׂינוּ מַה שֶּׁגָּזַרְתָּ עָלֵינוּ, אַף אַתָּה עֲשֵׂה עִמָּנוּ כְּמוֹ שֶׁהִבְטַחְתָּנוּ: הַשְׁקִיפָה מִמְּעוֹן קָדְשְׁךָ מִן הַשָּׁמַיִם, וּבָרֵךְ אֶת עַמְּךָ אֶת יִשְׂרָאֵל, וְאֵת הָאֲדָמָה אֲשֶׁר נָתַתָּה לָנוּ, כַּאֲשֶׁר נִשְׁבַּעְתָּ לַאֲבֹתֵינוּ, אֶרֶץ זָבַת חָלָב וּדְבָשׁ:","cond":["noTishaaBeav"]},{"kind":"instruction","text":"אם לא עלו כהנים לדוכן הש\"ץ אומר:","cond":["noTishaaBeav"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, בָּרְכֵנוּ בַּבְּרָכָה הַמְשֻׁלֶּשֶׁת בַּתּוֹרָה הַכְּתוּבָה עַל יְדֵי מֹשֶׁה עַבְדֶּךָ, הָאֲמוּרָה מִפִּי אַהֲרֹן וּבָנָיו כֹּהֲנִים עַם קְדוֹשֶׁךָ, כָּאָמוּר: יְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ: יָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ: יִשָּׂא יהוה פָּנָיו אֵלֶיךָ וְיָשֵׂם לְךָ שָׁלוֹם:","cond":["noTishaaBeav"]},{"kind":"text","text":"שִׂים שָׁלוֹם טוֹבָה וּבְרָכָה, חֵן וָחֶסֶד וְרַחֲמִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל עַמֶּךָ, בָּרְכֵנוּ אָבִינוּ כֻּלָּנוּ כְּאֶחָד בְּאוֹר פָּנֶיךָ, כִּי בְאוֹר פָּנֶיךָ נָתַתָּ לָּנוּ יהוה אֱלֹהֵינוּ תּוֹרַת חַיִּים וְאַהֲבַת חֶסֶד, וּצְדָקָה וּבְרָכָה וְרַחֲמִים וְחַיִּים וְשָׁלוֹם, וְטוֹב בְּעֵינֶיךָ לְבָרֵךְ אֶת עַמְּךָ יִשְׂרָאֵל בְּכָל עֵת וּבְכָל שָׁעָה בִּשְׁלוֹמֶךָ.","cond":[]},{"kind":"special","text":"בְּסֵפֶר חַיִּים, בְּרָכָה וְשָׁלוֹם, וּפַרְנָסָה טוֹבָה, נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ, אֲנַחְנוּ וְכָל עַמְּךָ בֵּית יִשְׂרָאֵל, לְחַיִּים טוֹבִים וּלְשָׁלוֹם.","cond":["ayt"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הַמְבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם.","cond":[]},{"kind":"text","text":"יִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:","cond":[]},{"kind":"header","text":"סדר נטילת לולב","cond":["sucot"]},{"kind":"instruction","text":"סדר נטילת לולב\n\nיקח את הלולב, ההדסים והערבות בידו הימנית כאשר שדרת הלולב תפנה אליו, והם מצביעים למעלה \"כדרך גידולם\". את האתרוג ייקח בידו השמאלית ויחזיקו הפוך, כלומר העוקץ (מיקום חיבורו לעץ) מופנה כלפי מעלה.","cond":["sucot"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ עַל נְטִילַת לוּלָב.","cond":["sucot"]},{"kind":"text","text":"בָּרוּךְ אַָתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁהֶחֱיָנוּ וְקִיְּמָנוּ וְהִגִּיעָנוּ לַזְּמַן הַזֶּה.","cond":["sucot","lulav_shehecheyanu"]},{"kind":"instruction","text":"לאחר הברכה הופכים את האתרוג ומחזיקים אותו כדרך גידולו כך שהפיטם פונה כלפי מעלה. לאחר מכן מקרבים את הלולב והאתרוג יחד ומנענעים אותם לכל הכיוונים.","cond":["sucot"]},{"kind":"header","text":"הלל","cond":["hallel"]},{"kind":"instruction","text":"הלל","cond":["hallel"]},{"kind":"instruction","text":"הנוהגים להניח תפילין בחול המועד יחלצו את התפילין לפני קריאת ההלל. שליח הציבור יחלצם לאחר אמירת הקדיש שלאחר הלל (משנ\"ב כ\"ה ס\"ק ס'). לאחר מכן אין מניחים שוב את התפילין, וכן לא מניחים תפילין דרבינו תם.","cond":["hallel","pesach"]},{"kind":"instruction","text":"הנוהגים להניח תפילין בחול המועד יחלצו את התפילין לפני קריאת ההלל. שליח הציבור גם כן יחלוץ כאן את התפילין בזמן שהקהל מתעסק בארבעת המינים (משנ\"ב כ\"ה ס\"ק ס'). לאחר מכן אין מניחים שוב את התפילין, וכן לא מניחים תפילין דרבינו תם.","cond":["hallel","sucot"]},{"kind":"instruction","text":"יש המברכים על הלל ביום העצמאות וביום שחרור ירושלים ויש שאינם מברכים, ויש שאינם אומרים הלל כלל בימים אלה.","cond":["hallel","yerushalayim"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ לִקְרֹא אֶת הַהַלֵּל.","cond":["hallel"]},{"kind":"text","text":"הַלְלוּיָהּ, הַלְלוּ עַבְדֵי יהוה, הַלְלוּ אֶת שֵׁם יהוה: יְהִי שֵׁם יהוה מְבֹרָךְ מֵעַתָּה וְעַד עוֹלָם: מִמִּזְרַח שֶׁמֶשׁ עַד מְבוֹאוֹ מְהֻלָּל שֵׁם יהוה: רָם עַל כָּל גּוֹיִם יהוה, עַל הַשָּׁמַיִם כְּבוֹדוֹ: מִי כַּיהוה אֱלֹהֵינוּ הַמַּגְבִּיהִי לָשָׁבֶת: הַמַּשְׁפִּילִי לִרְאוֹת בַּשָּׁמַיִם וּבָאָרֶץ: מְקִימִי מֵעָפָר דָּל, מֵאַשְׁפֹּת יָרִים אֶבְיוֹן: לְהוֹשִׁיבִי עִם נְדִיבִים, עִם נְדִיבֵי עַמּוֹ: מוֹשִׁיבִי עֲקֶרֶת הַבַּיִת, אֵם הַבָּנִים שְׂמֵחָה הַלְלוּיָהּ:","cond":["hallel"]},{"kind":"text","text":"בְּצֵאת יִשְׂרָאֵל מִמִּצְרָיִם, בֵּית יַעֲקֹב מֵעַם לֹעֵז: הָיְתָה יְהוּדָה לְקָדְשׁוֹ, יִשְׂרָאֵל מַמְשְׁלוֹתָיו: הַיָּם רָאָה וַיָּנֹס, הַיַּרְדֵּן יִסֹּב לְאָחוֹר: הֶהָרִים רָקְדוּ כְאֵילִים, גְּבָעוֹת כִּבְנֵי צֹאן: מַה לְּךָ הַיָּם כִּי תָנוּס, הַיַּרְדֵּן תִּסֹּב לְאָחוֹר: הֶהָרִים תִּרְקְדוּ כְאֵילִים, גְּבָעוֹת כִּבְנֵי צֹאן: מִלִּפְנֵי אָדוֹן חוּלִי אָרֶץ, מִלִּפְנֵי אֱלוֹהַּ יַעֲקֹב: הַהֹפְכִי הַצּוּר אֲגַם מָיִם, חַלָּמִישׁ לְמַעְיְנוֹ מָיִם:","cond":["hallel"]},{"kind":"text","text":"לֹא לָנוּ, יהוה, לֹא לָנוּ, כִּי לְשִׁמְךָ תֵּן כָּבוֹד עַל חַסְדְּךָ עַל אֲמִתֶּךָ: לָמָּה יֹאמְרוּ הַגּוֹיִם אַיֵּה נָא אֱלֹהֵיהֶם: וֵאלֹהֵינוּ בַשָּׁמָיִם כֹּל אֲשֶׁר חָפֵץ עָשָׂה: עֲצַבֵּיהֶם כֶּסֶף וְזָהָב, מַעֲשֵׂה יְדֵי אָדָם: פֶּה לָהֶם וְלֹא יְדַבֵּרוּ, עֵינַיִם לָהֶם וְלֹא יִרְאוּ: אָזְנַיִם לָהֶם וְלֹא יִשְׁמָעוּ, אַף לָהֶם וְלֹא יְרִיחוּן: יְדֵיהֶם וְלֹא יְמִישׁוּן, רַגְלֵיהֶם וְלֹא יְהַלֵּכוּ, לֹא יֶהְגּוּ בִּגְרוֹנָם: כְּמוֹהֶם יִהְיוּ עֹשֵׂיהֶם, כֹּל אֲשֶׁר בֹּטֵחַ בָּהֶם: יִשְׂרָאֵל בְּטַח בַּיהוה, עֶזְרָם וּמָגִנָּם הוּא: בֵּית אַהֲרֹן בִּטְחוּ בַיהוה, עֶזְרָם וּמָגִנָּם הוּא: יִרְאֵי יהוה בִּטְחוּ בַיהוה, עֶזְרָם וּמָגִנָּם הוּא:","cond":["hallel","fullHallel"]},{"kind":"text","text":"יהוה זְכָרָנוּ יְבָרֵךְ, יְבָרֵךְ אֶת בֵּית יִשְׂרָאֵל, יְבָרֵךְ אֶת בֵּית אַהֲרֹן: יְבָרֵךְ יִרְאֵי יהוה, הַקְּטַנִּים עִם הַגְּדֹלִים: יֹסֵף יהוה עֲלֵיכֶם, עֲלֵיכֶם וְעַל בְּנֵיכֶם: בְּרוּכִים אַתֶּם לַיהוה, עֹשֵׂה שָׁמַיִם וָאָרֶץ: הַשָּׁמַיִם שָׁמַיִם לַיהוה, וְהָאָרֶץ נָתַן לִבְנֵי אָדָם: לֹא הַמֵּתִים יְהַלְלוּ יָהּ, וְלֹא כָּל יֹרְדֵי דוּמָה: וַאֲנַחְנוּ נְבָרֵךְ יָהּ מֵעַתָּה וְעַד עוֹלָם הַלְלוּיָהּ:","cond":["hallel"]},{"kind":"text","text":"אָהַבְתִּי כִּי יִשְׁמַע יהוה אֶת קוֹלִי תַּחֲנוּנָי: כִּי הִטָּה אָזְנוֹ לִי וּבְיָמַי אֶקְרָא: אֲפָפוּנִי חֶבְלֵי מָוֶת וּמְצָרֵי שְׁאוֹל מְצָאוּנִי, צָרָה וְיָגוֹן אֶמְצָא: וּבְשֵׁם יהוה אֶקְרָא, אָנָּה יהוה מַלְּטָה נַפְשִׁי: חַנּוּן יהוה וְצַדִּיק, וֵאלֹהֵינוּ מְרַחֵם: שֹׁמֵר פְּתָאיִם יהוה, דַּלּוֹתִי וְלִי יְהוֹשִׁיעַ: שׁוּבִי נַפְשִׁי לִמְנוּחָיְכִי כִּי יהוה גָּמַל עָלָיְכִי: כִּי חִלַּצְתָּ נַפְשִׁי מִמָּוֶת, אֶת עֵינִי מִן דִּמְעָה, אֶת רַגְלִי מִדֶּחִי: אֶתְהַלֵּךְ לִפְנֵי יהוה בְּאַרְצוֹת הַחַיִּים: הֶאֱמַנְתִּי כִּי אֲדַבֵּר אֲנִי עָנִיתִי מְאֹד: אֲנִי אָמַרְתִּי בְחָפְזִי כָּל הָאָדָם כֹּזֵב:","cond":["hallel","fullHallel"]},{"kind":"text","text":"מָה אָשִׁיב לַיהוה, כָּל תַּגְמוּלוֹהִי עָלָי: כּוֹס יְשׁוּעוֹת אֶשָּׂא, וּבְשֵׁם יהוה אֶקְרָא: נְדָרַי לַיהוה אֲשַׁלֵּם, נֶגְדָה נָּא לְכָל עַמּוֹ: יָקָר בְּעֵינֵי יהוה הַמָּוְתָה לַחֲסִידָיו: אָנָּה יהוה כִּי אֲנִי עַבְדֶּךָ, אֲנִי עַבְדְּךָ בֶּן אֲמָתֶךָ, פִּתַּחְתָּ לְמוֹסֵרָי: לְךָ אֶזְבַּח זֶבַח תּוֹדָה, וּבְשֵׁם יהוה אֶקְרָא: נְדָרַי לַיהוה אֲשַׁלֵּם, נֶגְדָה נָּא לְכָל עַמּוֹ: בְּחַצְרוֹת בֵּית יהוה, בְּתוֹכֵכִי יְרוּשָׁלָיִם הַלְלוּיָהּ:","cond":["hallel"]},{"kind":"text","text":"הַלְלוּ אֶת יהוה כָּל גּוֹיִם, שַׁבְּחוּהוּ כָּל הָאֻמִּים: כִּי גָבַר עָלֵינוּ חַסְדּוֹ, וֶאֱמֶת יהוה לְעוֹלָם הַלְלוּיָהּ:","cond":["hallel"]},{"kind":"instruction","text":"ארבעה פסוקים אלה אומר החזן פסוק פסוק והקהל עונה \"הוֹדוּ לַה'...\". ויש האומרים בלחש יחד עם החזן את הפסוק שהוא אומר. ויש בכך מנהגים שונים.","cond":["hallel"]},{"kind":"text","text":"הוֹדוּ לַיהוה כִּי טוֹב, כִּי לְעוֹלָם חַסְדּוֹ:\nיֹאמַר נָא יִשְׂרָאֵל, כִּי לְעוֹלָם חַסְדּוֹ:\nיֹאמְרוּ נָא בֵית אַהֲרֹן, כִּי לְעוֹלָם חַסְדּוֹ:\nיֹאמְרוּ נָא יִרְאֵי יהוה, כִּי לְעוֹלָם חַסְדּוֹ:","cond":["hallel"]},{"kind":"text","text":"מִן הַמֵּצַר קָרָאתִי יָהּ, עָנָנִי בַמֶּרְחָב יָהּ: יהוה לִי לֹא אִירָא, מַה יַּעֲשֶׂה לִי אָדָם: יהוה לִי בְּעֹזְרָי, וַאֲנִי אֶרְאֶה בְשֹׂנְאָי: טוֹב לַחֲסוֹת בַּיהוה מִבְּטֹחַ בָּאָדָם: טוֹב לַחֲסוֹת בַּיהוה מִבְּטֹחַ בִּנְדִיבִים: כָּל גּוֹיִם סְבָבוּנִי בְּשֵׁם יהוה כִּי אֲמִילַם: סַבּוּנִי גַם סְבָבוּנִי בְּשֵׁם יהוה כִּי אֲמִילַם: סַבּוּנִי כִדְבוֹרִים דֹּעֲכוּ כְּאֵשׁ קוֹצִים בְּשֵׁם יהוה כִּי אֲמִילַם: דַּחֹה דְחִיתַנִי לִנְפֹּל וַיהוה עֲזָרָנִי: עָזִּי וְזִמְרָת יָהּ וַיְהִי לִי לִישׁוּעָה: קוֹל רִנָּה וִישׁוּעָה בְּאָהֳלֵי צַדִּיקִים, יְמִין יהוה עֹשָׂה חָיִל: יְמִין יהוה רוֹמֵמָה, יְמִין יהוה עֹשָׂה חָיִל: לֹא אָמוּת כִּי אֶחְיֶה וַאֲסַפֵּר מַעֲשֵׂי יָהּ: יַסֹּר יִסְּרַנִּי יָּהּ וְלַמָּוֶת לֹא נְתָנָנִי: פִּתְחוּ לִי שַׁעֲרֵי צֶדֶק, אָבֹא בָם אוֹדֶה יָהּ: זֶה הַשַּׁעַר לַיהוה, צַדִּיקִים יָבֹאוּ בוֹ:","cond":["hallel"]},{"kind":"text","text":"אוֹדְךָ כִּי עֲנִיתָנִי וַתְּהִי לִי לִישׁוּעָה:\nאוֹדְךָ כִּי עֲנִיתָנִי וַתְּהִי לִי לִישׁוּעָה:\n\nאֶבֶן מָאֲסוּ הַבּוֹנִים, הָיְתָה לְרֹאשׁ פִּנָּה:\nאֶבֶן מָאֲסוּ הַבּוֹנִים, הָיְתָה לְרֹאשׁ פִּנָּה:\n\nמֵאֵת יהוה הָיְתָה זֹּאת, הִיא נִפְלָאת בְּעֵינֵינוּ:\nמֵאֵת יהוה הָיְתָה זֹּאת, הִיא נִפְלָאת בְּעֵינֵינוּ:\n\nזֶה הַיּוֹם עָשָׂה יהוה, נָגִילָה וְנִשְׂמְחָה בוֹ:\nזֶה הַיּוֹם עָשָׂה יהוה, נָגִילָה וְנִשְׂמְחָה בוֹ:","cond":["hallel"]},{"kind":"instruction","text":"פסוק \"אָנָּא יהוה הוֹשִׁיעָה נָּא, אָנָּא יהוה הַצְלִיחָה נָּא\" נחלק לשניים, ואומרים כל חלק פעמיים. נוהגים שהחזן אומר חלק והקהל חוזר אחריו.","cond":["hallel"]},{"kind":"text","text":"אָנָּא יהוה הוֹשִׁיעָה נָּא.\nאָנָּא יהוה הוֹשִׁיעָה נָּא.\n\nאָנָּא יהוה הַצְלִיחָה נָּא:\nאָנָּא יהוה הַצְלִיחָה נָּא:","cond":["hallel"]},{"kind":"text","text":"בָּרוּךְ הַבָּא בְּשֵׁם יהוה, בֵּרַכְנוּכֶם מִבֵּית יהוה:\nבָּרוּךְ הַבָּא בְּשֵׁם יהוה, בֵּרַכְנוּכֶם מִבֵּית יהוה:\n\nאֵל יהוה וַיָּאֶר לָנוּ אִסְרוּ חַג בַּעֲבֹתִים עַד קַרְנוֹת הַמִּזְבֵּחַ:\nאֵל יהוה וַיָּאֶר לָנוּ אִסְרוּ חַג בַּעֲבֹתִים עַד קַרְנוֹת הַמִּזְבֵּחַ:\n\nאֵלִי אַתָּה וְאוֹדֶךָּ, אֱלֹהַי אֲרוֹמְמֶךָּ:\nאֵלִי אַתָּה וְאוֹדֶךָּ, אֱלֹהַי אֲרוֹמְמֶךָּ:\n\nהוֹדוּ לַיהוה כִּי טוֹב, כִּי לְעוֹלָם חַסְדּוֹ:\nהוֹדוּ לַיהוה כִּי טוֹב, כִּי לְעוֹלָם חַסְדּוֹ:","cond":["hallel"]},{"kind":"text","text":"יְהַלְלוּךָ יהוה אֱלֹהֵינוּ כָּל מַעֲשֶׂיךָ, וַחֲסִידֶיךָ צַדִּיקִים עוֹשֵׂי רְצוֹנֶךָ, וְכָל עַמְּךָ בֵּית יִשְׂרָאֵל בְּרִנָּה יוֹדוּ וִיבָרְכוּ וִישַׁבְּחוּ וִיפָאֲרוּ וִירוֹמְמוּ וְיַעֲרִיצוּ וְיַקְדִּישׁוּ וְיַמְלִיכוּ אֶת שִׁמְךָ מַלְכֵּנוּ, כִּי לְךָ טוֹב לְהוֹדוֹת וּלְשִׁמְךָ נָאֶה לְזַמֵּר, כִּי מֵעוֹלָם וְעַד עוֹלָם אַתָּה אֵל. בָּרוּךְ אַתָּה יהוה, מֶלֶךְ מְהֻלָּל בַּתִּשְׁבָּחוֹת.","cond":["hallel"]},{"kind":"instruction","text":"קדיש תתקבל","cond":["hallel","musaf"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":["hallel","musaf"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["hallel","musaf","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["hallel","musaf","ayt"]},{"kind":"text","text":"תִּתְקַבַּל צְלוֹתְהוֹן וּבָעוּתְהוֹן דְּכָל יִשְׂרָאֵל קֳדָם אֲבוּהוֹן דִּי בִשְׁמַיָּא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["hallel","musaf"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["hallel","musaf","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["hallel","musaf","ayt"]},{"kind":"header","text":"אבינו מלכנו","cond":["avinu_malkenu_kipur"]},{"kind":"instruction","text":"אבינו מלכנו","cond":["avinu_malkenu_kipur"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חָטָאנוּ לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, אֵין לָנוּ מֶלֶךְ אֶלָּא אָתָּה.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה עִמָּנוּ לְמַעַן שְׁמֶךָ.","cond":["avinu_malkenu_kipur"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חַדֵּשׁ עָלֵינוּ שָׁנָה טוֹבָה.","cond":["avinu_malkenu_kipur","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, בָּרֵךְ עָלֵינוּ שָׁנָה טוֹבָה.","cond":["avinu_malkenu_kipur","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, בַּטֵּל מֵעָלֵינוּ כָּל גְּזֵרוֹת קָשׁוֹת.\nאָבִינוּ מַלְכֵּנוּ, בַּטֵּל מַחְשְׁבוֹת שׂוֹנְאֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, הָפֵר עֲצַת אוֹיְבֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה כָּל צַר וּמַשְׂטִין מֵעָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, סְתֹם פִּיּוֹת מַשְׂטִינֵינוּ וּמְקַטְרְגֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה דֶבֶר וְחֶרֶב וְרָעָב וּשְׁבִי וּמַשְׁחִית וְעָוׂן וּשְׁמַד מִבְּנֵי בְרִיתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, מְנַע מַגֵּפָה מִנַּחֲלָתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, סְלַח וּמְחַל לְכָל עֲוׂנוֹתֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, מְחֵה וְהַעֲבֵר פְּשָׁעֵינוּ וְחַטֹּאתֵינוּ מִנֶּגֶד עֵינֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, מְחֹק בְּרַחֲמֶיךָ הָרַבִּים כָּל שִׁטְרֵי חוֹבוֹתֵינוּ.","cond":["avinu_malkenu_kipur"]},{"kind":"instruction","text":"מכאן אומרים בקול עם החזן","cond":["avinu_malkenu_kipur"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, הַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, שְׁלַח רְפוּאָה שְׁלֵמָה לְחוֹלֵי עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, קְרַע רֹע גְּזַר דִּינֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ בְּזִכְרוֹן טוֹב לְפָנֶיךָ.","cond":["avinu_malkenu_kipur"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר חַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר גְּאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר פַּרְנָסָה וְכַלְכָּלָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר זְכֻיּוֹת.\nאָבִינוּ מַלְכֵּנוּ, כָָּתְבֵנוּ בְּסֵפֶר סְלִיחָה וּמְחִילָה.","cond":["avinu_malkenu_kipur","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לְחַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִגְאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לְפַרְנָסָה וְכַלְכָּלָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִזְכֻיּוֹת.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִסְלִיחָה וּמְחִילָה.","cond":["avinu_malkenu_kipur","noGedalya"]},{"kind":"instruction","text":"עד כאן עם החזן","cond":["avinu_malkenu_kipur"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, הַצְמַח לָנוּ יְשׁוּעָה בְּקָרוֹב.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן יִשְׂרָאֵל עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן מְשִׁיחֶךָ.\nאָבִינוּ מַלְכֵּנוּ, מַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, מַלֵּא אֲסָמֵינוּ שָׂבָע.\nאָבִינוּ מַלְכֵּנוּ, שְׁמַע קוֹלֵנוּ, חוּס וְרַחֵם עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, קַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, פְּתַח שַׁעֲרֵי שָׁמַיִם לִתְפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, זְכֹר כִּי עָפָר אֲנַחְנוּ.\nאָבִינוּ מַלְכֵּנוּ, נָא אַל תְּשִׁיבֵנוּ רֵיקָם מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, תְּהֵא הַשָּׁעָה הַזֹּאת שְׁעַת רַחֲמִים וְעֵת רָצוֹן מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, חֲמֹל עָלֵינוּ וְעַל עוֹלָלֵינוּ וְטַפֵּנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן הֲרוּגִים עַל שֶׁם קָדְשֶׁךָ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן טְבוּחִים עַל יִחוּדֶךָ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן בָּאֵי בָאֵשׁ וּבַמָּיִּם עַל קִדּוּשׁ שְׁמֶךָ.\nאָבִינוּ מַלְכֵּנוּ, נְקֹם לְעֵינֵינוּ נִקְמַת דַּם עֲבָדֶיךָ הַשָּׁפוּךְ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַנְךָ אִם לֹא לְמַעַנֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַנְךָ וְהוֹשִׁיעֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַן רַחֲמֶיךָ הָרַבִּים.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַן שִׁמְךָ הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא שֶׁנִּקְרָא עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, חָנֵּנוּ וַעֲנֵנוּ כִּי אֵין בָּנוּ מַעֲשִׂים, עֲשֵׂה עִמָּנוּ צְדָקָה וָחֶסֶד וְהוֹשִׁיעֵנוּ.","cond":["avinu_malkenu_kipur"]},{"kind":"header","text":"סליחות לשבעה עשר בתמוז","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"סליחות לשבעה עשר בתמוז","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"סְלַח לָנוּ אָבִינוּ כִּי בְּרֹב אִוַּלְתֵּנוּ שָׁגִינוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי רַבּוּ עֲוׂנֵינוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אֵל אֶרֶךְ אַפַּיִם אַתָּה וּבַעַל הָרַחֲמִים נִקְרֵאתָ, וְדֶרֶךְ תְּשׁוּבָה הוֹרֵיתָ, גְּדֻלַּת רַחֲמֶיךָ וַחֲסָדֶיךָ תִּזְכֹּר הַיּוֹם וּבְכָל יוֹם לְזֶרַע יְדִידֶיךָ. תֵּפֶן אֵלֵינוּ בְּרַחֲמִים, כִּי אַתָּה הוּא בַּעַל הָרַחֲמִים. בְּתַחֲנוּן וּבִתְפִלָּה פָּנֶיךָ נְקַדֵּם, כְּהוֹדַעתָּ לֶעָנָו מִקֶּדֶם. מֵחֲרוֹן אַפְּךָ שׁוּב, כְּמוֹ בְּתוֹרָתְךָ כָּתוּב. וּבְצֵל כְּנָפֶיךָ נֶחְסֶה וְנִתְלוֹנָן, כְּיוֹם וַיֵּרֶד יהוה בֶּעָנָן. תַּעֲבֹר עַל פֶּשַׁע וְתִמְחֶה אָשָׁם, כְּיוֹם וַיִּתְיַצֵּב עִמּוֹ שָׁם. תַּאֲזִין שַׁוְעָתֵנוּ וְתַקְשִׁיב מֶנּוּ מַאֲמָר, כְּיוֹם וַיִּקְרָא בְשֵׁם יהוה, וְשָׁם נֶאֲמַר:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אַל תִּתְּנוּ דֳמִי לוֹ, עַד יְכוֹנֵן וְעַד יָשִׂים אֶת יְרוּשָׁלַיִם תְּהִלָּה בָּאָרֶץ: כִּי עִמְּךָ מְקוֹר חַיִּים, בְּאוֹרְךָ נִרְאֶה אוֹר: אֱלֹהֵינוּ, בּוֹשְׁנוּ בְּמַעֲשֵׂינוּ וְנִכְלַמְנוּ בַּעֲוׂנֵינוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"כְּרַחֵם אָב עַל בָּנִים, כֵּן תְּרַחֵם יהוה עָלֵינוּ. לַיהוה הַיְּשׁוּעָה, עַל עַמְּךָ בִרְכָתֶךָ סֶּלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶּלָה: יהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"סְלַח נָא לַעֲוׂן הָעָם הַזֶּה כְּגֹדֶל חַסְדֶּךָ, וְכַאֲשֶׁר נָשָׂאתָה לָעָם הַזֶּה מִמִּצְרַיִם וְעַד הֵנָּה: וְשָׁם נֶאֱמַר:","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"קהל ואחריו שליח הציבור:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"וַיֹּאמֶר יהוה: סָלַחְתִּי כִּדְבָרֶךָ:\n\nהַטֵּה אֱלֹהַי אָזְנְךָ וּשֲׁמָע, פְּקַח עֵינֶיךָ וּרְאֵה שׁוֹמְמוֹתֵינוּ וְהָעִיר אֲשֶׁר נִקְרָא שִׁמְךָ עָלֶיהָ, כִּי לֹא עַל צִדְקוֹתֵינוּ אֲנַחְנוּ מַפִּילִים תַּחֲנוּנֵינוּ לְפָנֶיךָ, כִּי עַל רַחֲמֶיךָ הָרַבִּים: אֲדֹנָי שְׁמָעָה, אֲדֹנָי סְלָחָה, אֲדֹנָי הַקְשִׁיבָה וַעֲשֵׂה אַל תְּאַחַר, לְמַעַנְךָ אֱלֹהַי, כִּי שִׁמְךָ נִקְרָא עַל עִירְךָ וְעַל עַמֶּךָ:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אָתָאנוּ לְךָ יוֹצֵר רוּחוֹת, בְּרוֹב עֲוׂנֵינוּ כָּבְדוּ אֲנָחוֹת, גְּזֵרוֹת עָצְמוּ וְרַבּוּ צְרִיחוֹת, כִּי בְּשִׁבְעָה עָשָׂר בְּתַמּוּז נִשְׁתַּבְּרוּ הַלּוּחוֹת. גָּלִינוּ מִבֵּית הַבְּחִירָה, דִּינֵנוּ נֶחְתַּם וְנִגְזְרָה גְזֵרָה, וְחָשַׁךְ בַּעֲדֵנוּ אוֹרָה, כִּי בְּשִׁבְעָה עָשָׂר בְּתַמּוּז נִשְׂרְפָה הַתּוֹרָה. הָרְסוּ אוֹיְבֵינוּ הַהֵיכָל, וּבָרְחָה שְׁכִינָה מִזָּוִית הֵיכָל, וְנִמְסַרְנוּ בִּידֵי זֵדִים לְהִתְאַכָּל, כִּי בְּשִׁבְעָה עָשָׂר בְּתַמּוּז הָעֳמַד צֶלֶם בְּהֵיכָל. זֵרוּנוּ מֵעִיר אֶל עִיר, וְנִלְכַּד מֶנּוּ רַב וְצָעִיר, חָרְבָה מְשׂוֹשֵׂנו וְאֵשׁ בָּהּ הִבְעִיר, כִּי בְּשִׁבְעָה עָשָׂר בְּתַמּוּז הָבְקְעָה הָעִיר. טָפַשׁ מִקְדָּשֵׁנוּ צַר הַמַּשְׁמִיד, וְנֻטַּל מֵחָתָן וְכַלָּה אֶצְעָדָה וְצָמִיד, יַעַן כִּעַסְנוּךָ נִתַּנּוּ לְהַשְׁמִיד, כִּי בְּשִׁבְעָה עָשָׂר בְּתַמּוּז בֻּטַּל הַתָּמִיד. כָּלָה מֶנּוּ כָּל הוֹד וָשֶׁבַח, חַרְבּוֹ שָׁלַף אוֹיֵב עָלֵינוּ לָאֶבַח, לִהְיוֹת עוֹלְלִים וְיוֹנְקִים מוּכָנִים לַטֶּבַח, כִּי בְּשִׁבְעָה עָשָׂר בְּתַמּוּז בָּטְלוּ עוֹלָה וָזָבַח. מָרַדְנוּ לְשׁוֹכֵן מְעוֹנוֹת, לָכֵן נִתְפַּזַּרְנוּ בְּכָל פִּנּוֹת, נֶהְפַּךְ מְחוֹלֵנוּ לְקִינוֹת, כִּי בְּשִׁבְעָה עָשָׂר בְּתַמּוּז בָּטְלוּ קָרְבָּנוֹת. סָרַרְנוּ לְפָנֶיךָ מֵרִיב לְשׁוֹנוֹת, לָכֵן לָמְדָה לְשׁוֹנֵנוּ לוֹמַר קִינוֹת, עֻזַּבְנוּ בְּלִי לְהִמָּנוֹת, כִּי בְּשִׁבְעָה עָשָׂר בְּתַמּוּז גָּרְמוּ לָנוּ עֲוׂנוֹת. פֻּזַּרְנוּ בְּלִי מְצוֹא רְוָחָה, לָכֵן רָבְתָה בָּנוּ אֲנָחָה, צוּר רְאֵה נַפְשֵׁנוּ כִּי שָׁחָה, וְשִׁבְעָה עָשָׂר בְּתַמּוּז הֲפָךְ לָנוּ לְשָׂשׂוֹן וּלְשִׂמְחָה. קִשִּׁינוּ עֹרֶף וְרָבְתָה בָּנוּ אָסוֹן, לָכֵן נִתַּנּוּ לִמְשִׁסָּה וְרִפְשׁוֹן, רְאֵה יהוה וְחַלְּצֵנוּ מֵאָסוֹן, וְשִׁבְעָה עָשָׂר בְּתַמּוּז הֲפָךְ לָנוּ לְשִׂמְחָה וּלְשָׂשׂוֹן. שְׁעֵנוּ שׁוֹכֵן רוּמָה, וְקַבֵּץ נְפוּצוֹתֵינוּ מִקַּצְווֹת אֲדָמָה, תֹּאמַר לְצִיּוֹן קוּמָה, וְשִׁבְעָה עָשָׂר בְּתַמּוּז הֲפָךְ לָנוּ לְיוֹם יְשׁוּעָה וְנֶחָמָה.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, מִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לְחַטָּאִים, וּסְלִיחָה לְפוֹשְׁעִים. עֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וָרוּחַ, לֹא כְרָעָתָם תִּגְמֹל. אֵל, הוֹרֵיתָ לָּנוּ לוֹמַר שְׁלֹשׁ עֶשְׂרֵה, וּזְכָר לָנוּ הַיּוֹם בְּרִית שְׁלשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָיו מִקֶּדֶם, כְּמוֹ שֶׁכָּתוּב: וַיֵּרֶד יהוה בֶּעָנָן, וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם, יהוה:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אֱלֹהִים, אַל דֳּמִי לָךְ, אַל תֶּחֱרַשׁ וְאַל תִּשְׁקוֹט אֵל: כִּי הִנֵּה אוֹיְבֶיךָ יֶהֱמָיוּן, וּמְשַׂנְאֶיךָ נָשְׂאוּ רֹאשׁ: אֵל נְקָמוֹת יהוה, אֵל נְקָמוֹת הוֹפִיעַ:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"כְּרַחֵם אָב עַל בָּנִים, כֵּן תְּרַחֵם יהוה עָלֵינוּ. לַיהוה הַיְּשׁוּעָה, עַל עַמְּךָ בִרְכָתֶךָ סֶּלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶּלָה: יהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֲמָרֵר בְּבֶכִי מִפְּנֵי יָד שְׁלוּחָה בְּעִי. בְּנַאֲצִי בְּתוֹךְ בֵּיתוֹ בְּבִגְדִי וְקָבְעִי. גָּח וּבָרַח וְנָסַע עֶשֶׂר וְעָלָה לַשְּׁבִיעִי. דִּמַּנִי הֱצִיקַנִי הִשִּׂיקַנִי בַּחֹדֶשׁ הָרְבִיעִי. הֵבִיא מוֹעֵד בִּמְלֵאָתוֹ לִשְׁבֹּר בַּחוּרֵי גִמּוּז. וְרִבָּה בוֹ פַעֲמַיִם בְּמִסְמוּס וּמִזְמוּז. זְבוּלוֹ כְּשָׁר שַׁאֲנַנּוֹת מְבַכּוֹת אֶת הַתַּמּוּז. חִיְּבַנִי וְאִיְּבַנִי אֲזַי בְּיֶרַח תַּמּוּז. טָמְנוּ פַחִים חֲמִשָּׁה בְּמִקְרָא תְּלָאוֹת מְשֻׁלָּחוֹת. יָכְלוּ לִי בְּשִׁבְעָה עָשָׂר בּוֹ בַּאֲלִיחוֹת. כִּי נוֹקַשְׁתִּי כְּכַלָּה עֲלוּבָה בְּחֻפַּת שַׁלְוָה וְהַצְלָחוֹת. לְרוֹעִי לֹא הִמְתַּנְתִּי שֵׁשׁ וְנִשְׁתַּבְּרוּ הַלֻּחוֹת. מִיָּדוֹ עָדִיתִי חֲלִי כֶתֶם, אֶצְעָדָה וְצָמִיד. נִגָּרוֹת בְּיוֹם אַפּוֹ, כְּשִׁחַתִּי דְרָכָי לְהַשְׁמִיד. סֵדֶר עֲבוֹדָתוֹ וְקַיִץ מִזְבְּחוֹ קַצְתִּי לְהַעֲמִיד. עַל כֵּן מִלִּשְׁכַּת הַטְּלָאִים בֻּטַּל הַתָּמִיד. פּוֹר הִתְפּוֹרְרָה וְנִתְפַּזְּרָה סוֹעֲרָה עֲנִיָּה. צִיָּה נִמְשְׁלָה מִבְּלִי חוֹבֵל, וְנִטְרְפָה כָּאֳנִיָּה. קַחְתָּהּ בְּחַטָּאתָהּ בְּרֹאשָׁהּ, וּבְכֶפֶל תַּאֲנִיָּה וַאֲנִיָּה. רִיבוּהָ צָרֶיהָ כְּהַיּוֹם וְהָבְקְעָה הָעִיר בַּשְּׁנִיָּה. שֻׁלְּחָה כִּצְבִי מֻדָּח מֵאֵין דּוֹרֵשׁ לְהַסְתִּירָה. שָׁנְנוּ לְשׁוֹנָם וּנְתָנוּהָ כְּשֶׂה, צַמְרָהּ וַחֲלָבָהּ לְהַתִּירָה. תִּצְעַק עַל כְּלִי חֶמְדָּה שֶׁבּוֹ נִכְתָּרָה. תַּחֲמוּד עֵינֶיהָ נֻצַּל כְּשָׂרַף אַפּוֹסְטְמוֹס הַתּוֹרָה. חֵרֵף עֲשׁוּקִים וּרְצוּצִים בַּעֲבוּר הַרְעִימָם סָכָל. יְרוּדִים בִּוְהָיָה לֶאֱכוֹל וּבְהַסְתֵּר פָּנִים מִלְּהִסְתַּכָּל. יָד הִשְׁלִים מִכְּנַף שִׁקּוּצִים נֶאֱכָל. עֵת צָרָה כְּהִתְכַּנֵּס וְהָעֳמַד צֶלֶם בְּהֵיכָל. דְּווּיִם סְגוּפִים בָּנִים הֶהָיוּ מִקֶּדֶם רִאשׁוֹנִים. סְמוּכוֹת צָרוֹתֵיהֶם זוֹ לְזוֹ כַּמֶּה שָׁנִים. לוֹקִים כַּאֲשֶׁר תַּעֲשֶׂינָה הַדְּבוֹרִים, וְהָעַקְרַבִּים שׁוֹנִים. הוֹגִים אָבַד שִׂבְרָם וּבָטֵל סִכּוּיָם בְּאִישׁוֹנִים. אֵל קַנָּא, בְּהִתְאַפֵּק בְּמַקְנִיאֶיךָ דְּשֵׁנִים רְטוּבִים. מְחַכִּים תָּקִים עוֹמְדִים לְעוֹלָמִים, כִּנְטִיעִים מְחֻטָּבִים בַּאֲהָבִים. הָאֱמֶת וְהַשָּׁלוֹם בְּצוֹמוֹת חֲטוּבִים. נֶצַח הֱיוֹתָם לְשִׂמְחָה וּלְשָׂשׂוֹן וּלְמוֹעֲדִים טוֹבִים.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, מִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לְחַטָּאִים, וּסְלִיחָה לְפוֹשְׁעִים. עֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וָרוּחַ, לֹא כְרָעָתָם תִּגְמֹל. אֵל, הוֹרֵיתָ לָּנוּ לוֹמַר שְׁלֹשׁ עֶשְׂרֵה, וּזְכָר לָנוּ הַיּוֹם בְּרִית שְׁלשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָיו מִקֶּדֶם, כְּמוֹ שֶׁכָּתוּב: וַיֵּרֶד יהוה בֶּעָנָן, וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם, יהוה:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"פזמון. שליח הציבור אומר את הבית הראשון, והקהל חוזר אחריו, ולאחר מכן כל בית הקהל אומר ושליח הציבור חוזר.","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"שְׁעֵה נֶאֱסַר, אֲשֶׁר נִמְסַר, בְּיַד בָּבֶל וְגַם שֵׂעִיר. לְךָ יֶהֱמֶה, זֶה כַּמֶּה, וְיִתְחַנֵּן כְּבֶן צָעִיר.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"יוֹם גָּבַר הָאוֹיֵב וַתִּבָּקַע הָעִיר.","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"לְזֹאת אִכַּף, וְאֶסְפֹּק כַּף, בְּיוֹם חִמֵּשׁ פִּזְרוֹנִי. וְעַל רֶגֶל הָעֵגֶל, הַלּוּחוֹת יְצָאוּנִי. וְגַם הִשְׁמִיד הַתָּמִיד, וּבַסּוּגַר הֱבִיאַנִי. וְהוּשַׂם אֱלִיל בְּהֵיכַל כְּלִיל, וּמֵעֲצָתוֹ כְּלָאַנִי. וְהַמִּנְחָה הוּנָחָה, וְדָתְךָ, צָר בָּאֵשׁ הִבְעִיר.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"יוֹם גָּבַר הָאוֹיֵב וַתִּבָּקַע הָעִיר.","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"מְאֹד אֶתְחַל, וָאֶתְחַלְחַל, בְּיוֹם שַׁדַּי דְּחָפַנִי. וְהַשְּׁפִיפוֹן מִצָּפוֹן, כְּשִׁבֹּלֶת שְׁטָפַנִי. מְאוֹר חָשַׁךְ, וְגַם שֵׁשַׁךְ, כְּמוֹ כַּדּוּר צְנָפַנִי. וְהַצַּיָּד שָׁלַח יָד, וְהַצָּפִיר וְהַשָּׂעִיר.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"יוֹם גָּבַר הָאוֹיֵב וַתִּבָּקַע הָעִיר.","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"הוֹד לִבִּי וּמִשְׂגַּבִּי, הֲלָעַד אַפְּךָ יֶעְשַׁן. הֲלֹא תִרְאֶה עַם נִלְאֶה, אֲשֶׁר הָשְׁחַר כְּמוֹ כִבְשָׁן. גְּדֹר פִּרְצִי בְּבֶן פַּרְצִי, וּמֵחֶדֶק לְקֹט שׁוֹשָׁן. בְּנֵה בֵּית זְבוּל, וְהָשֵׁב גְּבוּל הַכַּרְמֶל וְהַבָּשָׁן. וְעַיִן פְּקַח, וְנָקָם קַח מֵאֵצֶר וּמִדִּישָׁן. שְׁפֹט אִלֵּם, וְאָז יְשַׁלֵּם הַמַּבְעֶה וְהַמַּבְעִיר.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"יוֹם גָּבַר הָאוֹיֵב וַתִּבָּקַע הָעִיר.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, מִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לְחַטָּאִים, וּסְלִיחָה לְפוֹשְׁעִים. עֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וָרוּחַ, לֹא כְרָעָתָם תִּגְמֹל. אֵל, הוֹרֵיתָ לָּנוּ לוֹמַר שְׁלֹשׁ עֶשְׂרֵה, וּזְכָר לָנוּ הַיּוֹם בְּרִית שְׁלשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָיו מִקֶּדֶם, כְּמוֹ שֶׁכָּתוּב: וַיֵּרֶד יהוה בֶּעָנָן, וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם, יהוה:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"זְכֹר רַחֲמֶיךָ יהוה וַחֲסָדֶיךָ, כִּי מֵעוֹלָם הֵמָּה: זָכְרֵנוּ יהוה בִּרְצוֹן עַמֶּךָ, פָּקְדֵנוּ בִּישׁוּעָתֶךָ. זְכֹר עֲדָתְךָ קָנִיתָ קֶדֶם, גָּאַלְתָּ שֵׁבֶט נַחֲלָתֶךָ, הַר צִיּוֹן זֶה שָׁכַנְתָּ בּוֹ: זְכֹר יהוה חִבַּת יְרוּשָׁלָיִם, אַהֲבַת צִיּוֹן אַל תִּשְׁכַּח לָנֶצַח. אַתָּה תָקוּם תְּרַחֵם צִיּוֹן, כִּי עֵת לְחֶנְנָהּ, כִּי בָא מוֹעֵד: זְכֹר יהוה לִבְנֵי אֱדוֹם אֵת יוֹם יְרוּשָׁלָיִם, הָאוֹמְרִים עָרוּ עָרוּ, עַד הַיְסוֹד בָּהּ: זְכֹר לְאַבְרָהָם לְיִצְחָק וּלְיִשְׂרָאֵל עֲבָדֶיךָ, אֲשֶׁר נִשְׁבַּעְתָּ לָהֶם בָּךְ, וַתְּדַבֵּר אֲלֵהֶם, אַרְבֶּה אֶת זַרְעֲכֶם כְּכוֹכְבֵי הַשָּׁמַיִם, וְכָל הָאָרֶץ הַזֹּאת אֲשֶׁר אָמַרְתִּי אֶתֵּן לְזַרְעֲכֶם, וְנָחֲלוּ לְעוֹלָם: זְכֹר לַעֲבָדֶיךָ לְאַבְרָהָם לְיִצְחָק וּלְיַעֲקֹב, אַל תֵּפֶן אֶל קְשִׁי הָעָם הַזֶּה וְאֶל רִשְׁעוֹ וְאֶל חַטָּאתוֹ:\n\nאַל נָא תָשֵׁת עָלֵינוּ חַטָּאת אֲשֶׁר נוֹאַלְנוּ וַאֲשֶׁר חָטָאנוּ: חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"יש המוסיפים פיוט זה ואומרים אותו בית בית עם שליח הציבור:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אֵל נָא, רְפָא נָא תַּחֲלוּאֵי גֶפֶן פּוֹרִיָּה, בּוֹשָׁה וַחֲפוּרָה וְאֻמְלַל פִּרְיָהּ, גְּאָלֶנָּה מִשַּׁחַת וּמִמַּכָּה טְרִיָּה, עֲנֵנוּ כְּשֶׁעָנִיתָ לְאַבְרָהָם אָבִינוּ בְּהַר הַמּוֹרִיָּה.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"דִּגְלֵי עָם פְּדוּיֵי בִּזְרוֹעַ חָשׂוּף, הַצֵּל מִנֶּגֶף וְאַל יִהְיוּ לְשִׁסּוּף, וְתַעֲנֶה קְרִיאָתֵנוּ וּלְמַעֲשֵׂה יָדֶיךָ תִּכְסֹף, עֲנֵנוּ כְּשֶׁעָנִיתָ לַאֲבוֹתֵינוּ עַל יַם סוּף.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"זְכוּת צוּר חֻצַּב הַיּוֹם לָנוּ תְגַל, חָשְׂכֵנוּ מֵאֶנֶף וּנְחֵנוּ בְּיֹשֶׁר מַעְגָּל, טַהֵר טֻמְאָתֵנוּ וְלִמְאוֹר תּוֹרָתְךָ עֵינֵינוּ גַל, עֲנֵנוּ כְּשֶׁעָנִיתָ לִיהוֹשֻׁעַ בַּגִּלְגָּל.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"יָהּ, רְאֵה דֶשֶׁן עָקוּד וְהַצְמַח לָנוּ תְרוּפָה, כַּלֵּה שׁוֹד וָשֶׁבֶר, סַעַר וְסוּפָה, לַמְּדֵנוּ וְחַכְּמֵנוּ אִמְרָתְךָ הַצְּרוּפָה, עֲנֵנוּ כְּשֶׁעָנִיתָ לִשְׁמוּאֵל בַּמִּצְפָּה.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"מֻתְמָם מֵרֶחֶם שָׁרָשָׁיו אַל תַּקְמֵל, נַקֵּנוּ מִכֶּתֶם וְשֶׁמֶץ וְלֹא נֵאָמֵל, סְעָדֵנוּ וְנִוָּשֵׁעָה וְאָרְחוֹת חֲסָדֶיךָ נִגָּמֵל, עֲנֵנוּ כְּשֶׁעָנִיתָ לְאֵלִיָּהוּ בְּהַר הַכַּרְמֶל.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"עוֹדְדֵנוּ בְּצֶדֶק מָשׁוּי מִמַּיִם וְכַפֵּר זָדוֹן וּמְשׁוּגָה, פְּדֵנוּ מִמְּהוּמַת מָוֶת וְאָחוֹר בַּל נִסּוֹגָה, צַוֵּה יְשׁוּעָתֵנוּ וּבַעֲוׂנוֹתֵינוּ אַל נִתְמוֹגְגָה, עֲנֵנוּ כְּשֶׁעָנִיתָ לְיוֹנָה בִּמְעֵי הַדָּגָה.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"קְדֻשַּׁת אִישׁ חֲסִידֶךָ זְכֹר לִיפַת פַּעֲמַיִם, רַחֲמֶיךָ תְּעוֹרֵר כִּי לָקִינוּ בְּכִפְלַיִם, שׁוּבֵנוּ תֹּקֶף לְיִרְאָתֶךָ וְלֹא נֵחָשֵׂף שׁוּלַיִם, עֲנֵנוּ כְּשֶׁעָנִיתָ לְדָוִד וְלִשְׁלֹמֹה בְנוֹ בִּירוּשָׁלַיִם.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"בתענית אסתר יש מוסיפים:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"תַּעֲנֶה לְקוֹרְאֶיךָ וְהַסְכֵּת מִמְּעוֹנִים, תִּשְׁמַע שַׁוְעַת צוֹעֲקֶיךָ, שׁוֹמֵעַ אֶל אֶבְיוֹנִים, תְּרַחֵם עַל בָּנֶיךָ כְּרַחֵם אָב עַל בָּנִים, עֲנֵנוּ כְּמוֹ שֶׁעָנִיתָ לְמָרְדְּכַי וְאֶסְתֵּר, וְתָלוּ עַל עֵץ חֲמִשִּׁים הָאָב עִם הַבָּנִים.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"מכאן כולם אומרים:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"זְכֹר לָנוּ בְּרִית אָבוֹת כַּאֲשֶׁר אָמַרְתָּ: וְזָכַרְתִּי אֶת בְּרִיתִי יַעֲקוֹב וְאַף אֶת בְּרִיתִי יִצְחָק וְאַף אֶת בְּרִיתִי אַבְרָהָם אֶזְכֹּר, וְהָאָרֶץ אֶזְכֹּר:\n\nזְכֹר לָנוּ בְּרִית רִאשׁוֹנִים כַּאֲשֶׁר אָמַרְתָּ: וְזָכַרְתִּי לָהֶם בְּרִית רִאשׁוֹנִים אֲשֶׁר הוֹצֵאתִי אוֹתָם מֵאֶרֶץ מִצְרַיִם לְעֵינֵי הַגּוֹיִם לִהְיוֹת לָהֶם לֵאלֹהִים, אֲנִי יהוה:\n\nעֲשֵׂה עִמָּנוּ כְּמָה שֶׁהִבְטַחְתָּנוּ: וְאַף גַּם זֹאת בִּהְיוֹתָם בְּאֶרֶץ אוֹיְבֵיהֶם לֹא מְאַסְתִּים וְלֹא גְעַלְתִּים לְכַלּוֹתָם לְהָפֵר בְּרִיתִי אִתָּם, כִּי אֲנִי יהוה אֱלֹהֵיהֶם: הָשֵׁב שְׁבוּתֵנוּ וְרַחֲמֵנוּ כְּמָה שֶׁכָּתוּב: וְשָׁב יהוה אֱלֹהֶיךָ אֶת שְׁבוּתְךָ וְרִחֲמֶךָ, וְשָׁב וְקִבֶּצְךָ מִכָּל הָעַמִּים אֲשֶׁר הֱפִיצְךָ יהוה אֱלֹהֶיךָ שָׁמָּה: קַבֵּץ נִדָּחֵינוּ כְּמָה שֶׁכָּתוּב: אִם יִהְיֶה נִדַּחֲךָ בִּקְצֵה הַשָּׁמָיִם, מִשָּׁם יְקַבֶּצְךָ יהוה אֱלֹהֶיךָ וּמִשָּׁם יִקָּחֶךָ: מְחֵה פְשָׁעֵינוּ כָּעָב וְכֶעָנָן כְּמָה שֶׁכָּתוּב: מָחִיתִי כָעָב פְּשָׁעֶיךָ וְכֶעָנָן חַטֹּאתֶיךָ, שׁוּבָה אֵלַי כִּי גְאַלְתִּיךָ: מְחֵה פְשָׁעֵינוּ לְמַעַנְךָ כַּאֲשֶׁר אָמַרְתָּ: אָנֹכִי אָנֹכִי הוּא מֹחֶה פְשָׁעֶיךָ לְמַעֲנִי, וְחַטֹּאתֶיךָ לֹא אֶזְכֹּר: הַלְבֵּן חֲטָאֵינוּ כַּשֶּׁלֶג וְכַצֶּמֶר כְּמָה שֶׁכָּתוּב: לְכוּ נָא וְנִוָּכְחָה יֹאמַר יהוה, אִם יִהְיוּ חֲטָאֵיכֶם כַּשָּׁנִים כַּשֶּׁלֶג יַלְבִּינוּ, אִם יַאְדִּימוּ כַתּוֹלָע כַּצֶּמֶר יִהְיוּ: זְרֹק עָלֵינוּ מַיִם טְהוֹרִים וְטַהֲרֵנוּ כְּמָה שֶׁכָּתוּב: וְזָרַקְתִּי עֲלֵיכֶם מַיִם טְהוֹרִים וּטְהַרְתֶּם, מִכֹּל טֻמְאֹתֵיכֶם וּמִכָּל גִּלּוּלֵיכֶם אֲטַהֵר אֶתְכֶם: רַחֵם עָלֵינוּ וְאַל תַּשְׁחִיתֵנוּ כְּמָה שֶׁכָּתוּב: כִּי אֵל רַחוּם יהוה אֱלֹהֶיךָ, לֹא יַרְפְּךָ וְלֹא יַשְׁחִיתֶךָ, וְלֹא יִשְׁכַּח אֶת בְּרִית אֲבֹתֶיךָ אֲשֶׁר נִשְׁבַּע לָהֶם: מוֹל אֶת לְבָבֵנוּ לְאַהֲבָה אֶת שְׁמֶךָ כְּמָה שֶׁכָּתוּב: וּמָל יהוה אֱלֹהֶיךָ אֶת לְבָבְךָ וְאֶת לְבַב זַרְעֶךָ, לְאַהֲבָה אֶת יהוה אֱלֹהֶיךָ בְּכָל לְבָבְךָ וּבְכָל נַפְשְׁךָ, לְמַעַן חַיֶּיךָ: הִמָּצֵא לָנוּ בְּבַקָּשָׁתֵנוּ כְּמָה שֶׁכָּתוּב: וּבִקַּשְׁתֶּם מִשָּׁם אֶת יהוה אֱלֹהֶיךָ וּמָצָאתָ, כִּי תִדְרְשֶׁנּוּ בְּכָל לְבָבְךָ וּבְכָל נַפְשֶׁךָ: תְּבִיאֵנוּ אֶל הַר קָדְשֶׁךָ וְשַׂמְּחֵנוּ בְּבֵית תְּפִלָּתֶךָ כְּמָה שֶׁכָּתוּב: וַהֲבִיאוֹתִים אֶל הַר קָדְשִׁי וְשִׂמַּחְתִּים בְּבֵית תְּפִלָּתִי, עוֹלוֹתֵיהֶם וְזִבְחֵיהֶם לְרָצוֹן עַל מִזְבְּחִי, כִּי בֵיתִי, בֵּית תְּפִלָּה יִקָּרֵא לְכָל הָעַמִּים:","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"פותחים את ארון הקודש ואמורים משפט משפט. יש קהילות בהם סדר המשפטים שונה וברוב הקהילות מדלגים על המשפט \"יהיו לרצון\".","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"שְׁמַע קוֹלֵנוּ, יהוה אֱלֹהֵינוּ, חוּס וְרַחֵם עָלֵינוּ, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ. הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם: אֲמָרֵינוּ הַאֲזִינָה יהוה, בִּינָה הֲגִיגֵנוּ. יִהְיוּ לְרָצוֹן אִמְרֵי פִינוּ וְהֶגְיוֹן לִבֵּנוּ לְפָנֶיךָ, יהוה צוּרֵנוּ וְגוֹאֲלֵנוּ. אַל תַּשְׁלִיכֵנוּ מִלְּפָנֶיךָ, וְרוּחַ קָדְשְׁךָ אַל תִּקַּח מִמֶּנּוּ. אַל תַּשְׁלִיכֵנוּ לְעֵת זִקְנָה, כִּכְלוֹת כֹּחֵנוּ אַל תַּעַזְבֵנוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"מכאן מפסיקים לומר עם החזן בקול.","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אַל תַּעַזְבֵנוּ יהוה, אֱלֹהֵינוּ אַל תִּרְחַק מִמֶּנוּ. עֲשֵׂה עִמָּנוּ אוֹת לְטוֹבָה, וְיִרְאוּ שׂוֹנְאֵינוּ וְיֵבוֹשׁוּ, כִּי אַתָּה יהוה עֲזַרְתָּנוּ וְנִחַמְתָּנוּ. כִּי לְךָ יהוה הוֹחָלְנוּ, אַתָּה תַעֲנֶה אֲדֹנָי אֱלֹהֵינוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"סוגרים את ארון הקודש.","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, תָּבוֹא לְפָנֶיךָ תְּפִלָּתֵנוּ וְאַל תִּתְעַלַּם מִתְּחִנָּתֵנוּ, שֶׁאֵין אָנוּ עַזֵּי פָנִים וּקְשֵׁי עֹרֶף לוֹמַר לְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ צַדִּיקִים אֲנַחְנוּ וְלֹא חָטָאנוּ, אֲבָל אֲנַחְנוּ וַאֲבוֹתֵינוּ חָטָאנוּ.\nאָשַׁמְנוּ, בָּגַדְנוּ, גָּזַלְנוּ, דִּבַּרְנוּ דֹפִי. הֶעֱוִינוּ, וְהִרְשַׁענוּ, זַדְנוּ, חָמַסְנוּ, טָפַלְנוּ שֶׁקֶר. יָעַצְנוּ רָע, כְּזַּבְנוּ, לַצְנוּ, מָרַדְנוּ, נִאַצְנוּ, סָרַרְנוּ, עָוְינוּ, פָּשַׁעְנוּ, צָרַרְנוּ, קִשִּׁינוּ עֹרֶף. רָשַׁעְנוּ, שִׁחַתְנוּ, תִּעַבְנוּ, תָּעִינוּ, תִּעְתַּעְנוּ.\nסַרְנוּ מִמִּצְוׂתֶיךָ וּמִמִּשְׁפָּטֶיךָ הַטּוֹבִים וְלֹא שָׁוָה-לָנוּ. וְאַתָּה צַדִּיק עַל כָּל הַבָּא עָלֵינוּ, כִּי אֱמֶת עָשִׂיתָ, וַאֲנַחְנוּ הִרְשָׁעְנוּ:\n\nהִרְשַׁעְנוּ וּפָשַׁעְנוּ לָכֵן לֹא נוֹשָׁעְנוּ. וְתֵן בְּלִבֵּנוּ לַעֲזֹב דֶּרֶךְ רֶשַׁע, וְחִישׁ לָנוּ יֶשַׁע, כַּכָּתוּב עַל יַד נְבִיאֶךָ: יַעֲזוֹב רָשָׁע דַּרְכּוֹ וְאִישׁ אָוֶן מַחְשְׁבֹתָיו, וְיָשֹׁב אֶל יהוה וִירַחֲמֵהוּ, וְאֶל אֱלֹהֵינוּ כִּי יַרְבֶּה לִסְלוֹחַ:\n\nמְשִׁיחַ צִדְקֶךָ אָמַר לְפָנֶיךָ: שְׁגִיאוֹת מִי יָבִין מִנִּסְתָּרוֹת נַקֵּנִי: נַקֵּנוּ יהוה אֱלֹהֵינוּ מִכָּל פְּשָׁעֵינוּ וְטַהֲרֵנוּ מִכָּל טֻמְאוֹתֵינוּ, וּזְרֹק עָלֵינוּ מַיִם טְהוֹרִים וְטַהֲרֵנוּ, כַּכָּתוּב עַל יַד נְבִיאֶךָ: וְזָרַקְתִּי עֲלֵיכֶם מַיִם טְהוֹרִים וּטְהַרְתֶּם, מִכֹּל טֻמְאוֹתֵיכֶם וּמִכָּל גִּלּוּלֵיכֶם אֲטַהֵר אֶתְכֶם: עַמְּךָ וְנַחֲלָתְךָ רְעֵבֵי טוּבְךָ, צְמֵאֵי חַסְדְּךָ, תְּאֵבֵי יִשְׁעֶךָ. יַכִּירוּ וְיֵדְעוּ כִּי לַיהוה אֱלֹהֵינוּ הָרַחֲמִים וְהַסְּלִיחוֹת.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"אם אין אומרים תחנון מדלגים על המשך הסליחות.","cond":["shacharitTachanun","17tammuz","shacharitTachanun"]},{"kind":"text","text":"אֵל רַחוּם שְׁמֶךָ. אֵל חַנּוּן שְׁמֶךָ. בָּנוּ נִקְרָא שְׁמֶךָ. יהוה עֲשֵׂה לְמַעַן שְׁמֶךָ. עֲשֵׂה לְמַעַן אֲמִתָּךְ. עֲשֵׂה לְמַעַן בְּרִיתָךְ. עֲשֵׂה לְמַעַן גָּדְלָךְ וְתִפְאַרְתָּךְ. עֲשֵׂה לְמַעַן דָּתָךְ. עֲשֵׂה לְמַעַן הוֹדָךְ. עֲשֵׂה לְמַעַן וִעוּדָךְ. עֲשֵׂה לְמַעַן זִכְרָךְ. עֲשֵׂה לְמַעַן חַסְדָּךְ. עֲשֵׂה לְמַעַן טוּבָךְ. עֲשֵׂה לְמַעַן יִחוּדָךְ. עֲשֵׂה לְמַעַן כְּבוֹדָךְ. עֲשֵׂה לְמַעַן לִמּוּדָךְ. עֲשֵׂה לְמַעַן מַלְכוּתָךְ. עֲשֵׂה לְמַעַן נִצְחָךְ. עֲשֵׂה לְמַעַן סוֹדָךְ. עֲשֵׂה לְמַעַן עֻזָּךְ. עֲשֵׂה לְמַעַן פְּאֵרָךְ. עֲשֵׂה לְמַעַן צִדְקָתָךְ. עֲשֵׂה לְמַעַן קְדֻשָׁתָךְ. עֲשֵׂה לְמַעַן רַחֲמֶיךָ הָרַבִּים. עֲשֵׂה לְמַעַן שְׁכִינָתָךְ. עֲשֵׂה לְמַעַן תְּהִלָּתָךְ. עֲשֵׂה לְמַעַן אוֹהֲבֶיךָ שׁוֹכְנֵי עָפָר. עֲשֵׂה לְמַעַן אַבְרָהָם יִצְחָק וְיַעֲקֹב. עֲשֵׂה לְמַעַן מֹשֶׁה וְאַהֲרֹן. עֲשֵׂה לְמַעַן דָּוִד וּשְׁלֹמֹה. עֲשֵׂה לְמַעַן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ. עֲשֵׂה לְמַעַן צִיּוֹן מִשְׁכַּן כְּבוֹדֶךָ. עֲשֵׂה לְמַעַן שִׁמְמוֹת הֵיכָלֶךָ. עֲשֵׂה לְמַעַן הֲרִיסוּת מִזְבְּחֶךָ. עֲשֵׂה לְמַעַן הֲרוּגִים עַל שֵׁם קָדְשֶׁךָ. עֲשֵׂה לְמַעַן טְבוּחִים עַל יִחוּדֶךָ. עֲשֵׂה לְמַעַן בָּאֵי בָאֵשׁ וּבַמַּיִם עַל קִדּוּשׁ שְׁמֶךָ. עֲשֵׂה לְמַעַן יוֹנְקֵי שָׁדַיִם שֶׁלֹּא חָטְאוּ. עֲשֵׂה לְמַעַן גְּמוּלֵי חָלָב שֶׁלֹּא פָשְׁעוּ. עֲשֵׂה לְמַעַן תִּינוֹקוֹת שֶׁל בֵּית רַבָּן. עֲשֵׂה לְמַעַנְךָ אִם לֹא לְמַעֲנֵנוּ. עֲשֵׂה לְמַעַנְךָ וְהוֹשִׁיעֵנוּ.\n\nעֲנֵנוּ יהוה עֲנֵנוּ. עֲנֵנוּ אֱלֹהֵינוּ עֲנֵנוּ. עֲנֵנוּ אָבִינוּ עֲנֵנוּ. עֲנֵנוּ בּוֹרְאֵנוּ עֲנֵנוּ. עֲנֵנוּ גּוֹאֲלֵנוּ עֲנֵנוּ. עֲנֵנוּ דּוֹרְשֵׁנוּ עֲנֵנוּ. עֲנֵנוּ הָאֵל הַנֶּאֱמָן עֲנֵנוּ. עֲנֵנוּ וָתִיק וְחָסִיד עֲנֵנוּ. עֲנֵנוּ זַךְ וְיָשָׁר עֲנֵנוּ. עֲנֵנוּ חַי וְקַיָּם עֲנֵנוּ. עֲנֵנוּ טוֹב וּמֵטִיב עֲנֵנוּ. עֲנֵנוּ יוֹדֵעַ יֶצֶר עֲנֵנוּ. עֲנֵנוּ כּוֹבֵשׁ כְּעָסִים עֲנֵנוּ. עֲנֵנוּ לוֹבֵשׁ צְדָקוֹת עֲנֵנוּ. עֲנֵנוּ מֶלֶךְ מַלְכֵי הַמְּלָכִים עֲנֵנוּ. עֲנֵנוּ נוֹרָא וְנִשְׂגָּב עֲנֵנוּ. עֲנֵנוּ סוֹלֵחַ וּמוֹחֵל עֲנֵנוּ. עֲנֵנוּ עוֹנֶה בְּעֵת צָרָה עֲנֵנוּ. עֲנֵנוּ פּוֹדֶה וּמַצִּיל עֲנֵנוּ. עֲנֵנוּ צַדִּיק וְיָשָׁר עֲנֵנוּ. עֲנֵנוּ קָרוֹב לְקוֹרְאָיו עֲנֵנוּ. עֲנֵנוּ רַחוּם וְחַנוּן עֲנֵנוּ. עֲנֵנוּ שׁוֹמֵעַ אֶל אֶבְיוֹנִים עֲנֵנוּ. עֲנֵנוּ תּוֹמֵךְ תְּמִימִים עֲנֵנוּ. עֲנֵנוּ אֱלֹהֵי אֲבוֹתֵינוּ עֲנֵנוּ. עֲנֵנוּ אֱלֹהֵי אַבְרָהָם עֲנֵנוּ. עֲנֵנוּ פַּחַד יִצְחָק עֲנֵנוּ. עֲנֵנוּ אֲבִיר יַעֲקֹב עֲנֵנוּ. עֲנֵנוּ עֶזְרַת הַשְּׁבָטִים עֲנֵנוּ. עֲנֵנוּ מִשְׂגַּב אִמָּהוֹת עֲנֵנוּ. עֲנֵנוּ קָשֶׁה לִכְעוֹס עֲנֵנוּ. עֲנֵנוּ רַךְ לִרְצוֹת עֲנֵנוּ. עֲנֵנוּ עוֹנֶה בְּעֵת רָצוֹן עֲנֵנוּ. עֲנֵנוּ אֲבִי יְתוֹמִים עֲנֵנוּ. עֲנֵנוּ דַּיַּן אַלְמָנוֹת עֲנֵנוּ.\n\nמִי שֶׁעָנָה לְאַבְרָהָם אָבִינוּ בְּהַר הַמּוֹרִיָּה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְיִצְחָק בְּנוֹ כְּשֶׁנֶּעֱקַד עַל גַּבֵּי הַמִּזְבֵּחַ הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְיַעֲקֹב בְּבֵית אֵל הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְיוֹסֵף בְּבֵית הָאֲסוּרִים הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לַאֲבוֹתֵינוּ עַל יַם סוּף הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְמֹשֶׁה בְּחוֹרֵב הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְאַהֲרֹן בַּמַּחְתָּה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְפִינְחָס בְּקוּמוֹ מִתּוֹךְ הָעֵדָה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לִיהוֹשֻׁעַ בַּגִּלְגָּל הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לִשְׁמוּאֵל בַּמִּצְפָּה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְדָוִד וּשְׁלֹמֹה בְנוֹ בִּירוּשָׁלָיִם הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְאֵלִיָּהוּ בְּהַר הַכַּרְמֶל הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לֶאֱלִישָׁע בִּירִיחוֹ הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְיוֹנָה בִּמְעֵי הַדָּגָה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְחִזְקִיָּהוּ מֶלֶךְ יְהוּדָה בְּחָלְיוֹ הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לַחֲנַנְיָה מִישָׁאֵל וַעֲזַרְיָה בְּתוֹךְ כִּבְשַׁן הָאֵשׁ הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְדָנִיֵּאל בְּגוֹב הָאֲרָיוֹת הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְמָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְעֶזְרָא בַּגּוֹלָה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְכָל הַצַּדִּיקִים וְהַחֲסִידִים וְהַתְּמִימִים וְהַיְּשָׁרִים הוּא יַעֲנֵנוּ.\n\nרַחֲמָנָא דְעָנֵי לַעֲנִיֵי עֲנֵינָא. רַחֲמָנָא דְעָנֵי לִתְבִירֵי לִבָּא עֲנֵינָן. רַחֲמָנָא דְעָנֵי לְמַכִּיכֵי רוּחָא עֲנֵינָן. רַחֲמָנָא עֲנֵינָן. רַחֲמָנָא חוּס. רַחֲמָנָא פְּרוֹק. רַחֲמָנָא שְׁזִיב. רַחֲמָנָא רְחַם עֲלָן. הַשְׁתָּא בַּעֲגָלָא וּבִזְמַן קָרִיב.","cond":["shacharitTachanun","17tammuz","shacharitTachanun"]},{"kind":"header","text":"סליחות לעשרה בטבת","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"סליחות לעשרה בטבת","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"סְלַח לָנוּ אָבִינוּ כִּי בְּרֹב אִוַּלְתֵּנוּ שָׁגִינוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי רַבּוּ עֲוׂנֵינוּ.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אֵל אֶרֶךְ אַפַּיִם אַתָּה וּבַעַל הָרַחֲמִים נִקְרֵאתָ, וְדֶרֶךְ תְּשׁוּבָה הוֹרֵיתָ, גְּדֻלַּת רַחֲמֶיךָ וַחֲסָדֶיךָ תִּזְכֹּר הַיּוֹם וּבְכָל יוֹם לְזֶרַע יְדִידֶיךָ. תֵּפֶן אֵלֵינוּ בְּרַחֲמִים, כִּי אַתָּה הוּא בַּעַל הָרַחֲמִים. בְּתַחֲנוּן וּבִתְפִלָּה פָּנֶיךָ נְקַדֵּם, כְּהוֹדַעתָּ לֶעָנָו מִקֶּדֶם. מֵחֲרוֹן אַפְּךָ שׁוּב, כְּמוֹ בְּתוֹרָתְךָ כָּתוּב. וּבְצֵל כְּנָפֶיךָ נֶחְסֶה וְנִתְלוֹנָן, כְּיוֹם וַיֵּרֶד יהוה בֶּעָנָן. תַּעֲבֹר עַל פֶּשַׁע וְתִמְחֶה אָשָׁם, כְּיוֹם וַיִּתְיַצֵּב עִמּוֹ שָׁם. תַּאֲזִין שַׁוְעָתֵנוּ וְתַקְשִׁיב מֶנּוּ מַאֲמָר, כְּיוֹם וַיִּקְרָא בְשֵׁם יהוה, וְשָׁם נֶאֲמַר:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"כִּי עִם יהוה הַחֶסֶד, וְהַרְבֵּה עִמּוֹ פְדוּת: פְּדֵה אֱלֹהִים אֶת יִשְׂרָאֵל מִכֹּל צָרוֹתָיו: וְהוּא יִפְדֶּה אֶת יִשְׂרָאֵל מִכֹּל עֲוׂנוֹתָיו: פּוֹדֶה יהוה נֶפֶשׁ עֲבָדָיו, וְלֹא יֶאְשְׁמוּ כָּל הַחוֹסִים בּוֹ:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"כְּרַחֵם אָב עַל בָּנִים, כֵּן תְּרַחֵם יהוה עָלֵינוּ. לַיהוה הַיְּשׁוּעָה, עַל עַמְּךָ בִרְכָתֶךָ סֶּלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶּלָה: יהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"סְלַח נָא לַעֲוׂן הָעָם הַזֶּה כְּגֹדֶל חַסְדֶּךָ, וְכַאֲשֶׁר נָשָׂאתָה לָעָם הַזֶּה מִמִּצְרַיִם וְעַד הֵנָּה: וְשָׁם נֶאֱמַר:","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"קהל ואחריו שליח הציבור:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"וַיֹּאמֶר יהוה: סָלַחְתִּי כִּדְבָרֶךָ:\n\nהַטֵּה אֱלֹהַי אָזְנְךָ וּשֲׁמָע, פְּקַח עֵינֶיךָ וּרְאֵה שׁוֹמְמוֹתֵינוּ וְהָעִיר אֲשֶׁר נִקְרָא שִׁמְךָ עָלֶיהָ, כִּי לֹא עַל צִדְקוֹתֵינוּ אֲנַחְנוּ מַפִּילִים תַּחֲנוּנֵינוּ לְפָנֶיךָ, כִּי עַל רַחֲמֶיךָ הָרַבִּים: אֲדֹנָי שְׁמָעָה, אֲדֹנָי סְלָחָה, אֲדֹנָי הַקְשִׁיבָה וַעֲשֵׂה אַל תְּאַחַר, לְמַעַנְךָ אֱלֹהַי, כִּי שִׁמְךָ נִקְרָא עַל עִירְךָ וְעַל עַמֶּךָ:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֶזְכְּרָה מָצוֹק אֲשֶׁר קְרָאַנִי, בְּשָׁלֹשׁ מַכּוֹת בַּחֹדֶשׁ הַזֶּה הִכַּנִי, גִּדְּעַנִי הֱנִיאַנִי הִכְאַנִי, אַךְ עַתָּה הֶלְאָנִי. דִּעֲכַנִי בִּשְׁמוֹנָה בוֹ שְׂמָאלִית וִימָנִית, הֲלֹא שְׁלָשְׁתָּן קָבַעְתִּי תַעֲנִית, וּמֶלֶךְ יָוָן אֲנָסַנִי לִכְתֹּב דָּת יְוָנִית, עַל גַּבִּי חָרְשׁוּ חוֹרְשִׁים, הֶאֱרִיכוּ מַעֲנִית. זוֹעַמְתִּי בְּתִשְׁעָה בוֹ בִּכְלִמָה וָחֵפֶר, חָשַׂךְ מֵעָלַי מְעִיל הוֹד וָצֶפֶר, טָרֹף טֹרַף בּוֹ הַנּוֹתֵן אִמְרֵי שֶׁפֶר, הוּא עֶזְרָא הַסּוֹפֵר. יוֹם עֲשִׂירִי צֻוָּה בֶּן בּוּזִי הַחוֹזֶה, כְּתָב לְךָ בְּסֵפֶר הַמַּחֲזֶה, לְזִכָּרוֹן לְעַם נָמֵס וְנִבְזֶה, אֶת עֶצֶם הַיּוֹם הַזֶּה. מִנְיַן סֵדֶר חֳדָשִׁים בַּעֲשָׂרָה בוֹ הֵעִיר, נְהִי וִילֵל בְּמוֹ פִי אַפְעִיר, סֵדֶר פֻּרְעָנֻיּוֹת בְּתוֹךְ לְבָבִי יַבְעִיר, בְּבֹא אֵלַי הַפָּלִיט לֵאמֹר הֻכְּתָה הָעִיר. עַל אֵלֶּה עַל פָּנַי אָבָק זֵרִיתִי, פַּצְתִּי עַל אַרְבַּעְתָּן לוּ חֵץ בְּלִבִּי יָרִיתִי, צָרוֹת עַל אֵלֶּה קֶבֶר לִי כָּרִיתִי. צַדִּיק הוּא יהוה כִּי פִיהוּ מָרִיתִי, קָרָאתִי שִׁמְךָ מִתְנַחֵם עַל רָעָתִי, רְאֵה עָנְיִי וּשְׁמַע קוֹל פְּגִיעָתִי, שְׁמַע תְּחִנָּתִי חִישׁ נָא יְשׁוּעָתִי, אַל תַּעְלֵם אָזְנְךָ לְרַוְחָתִי לְשַׁוְעָתִי: יֶרַח טֵבֵת מְאֹד לָקִיתִי בוֹ, וְנִשְׁתַּנּוּ עָלַי סִדְרֵי נְתִיבוֹ, סָרַרְתִּי פָּשַׁעְתִּי יְגַלֶּה לִי טוּבוֹ, הָאוֹמֵר לַיָּם עַד פֹּה תָבֹא.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, מִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לְחַטָּאִים, וּסְלִיחָה לְפוֹשְׁעִים. עֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וָרוּחַ, לֹא כְרָעָתָם תִּגְמֹל. אֵל, הוֹרֵיתָ לָּנוּ לוֹמַר שְׁלֹשׁ עֶשְׂרֵה, וּזְכָר לָנוּ הַיּוֹם בְּרִית שְׁלשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָיו מִקֶּדֶם, כְּמוֹ שֶׁכָּתוּב: וַיֵּרֶד יהוה בֶּעָנָן, וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם, יהוה:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אֱלֹהִים, בָּאוּ גוֹיִם בְּנַחֲלָתֶךָ, טִמְּאוּ אֶת הֵיכַל קָדְשֶׁךָ, שָׂמוּ אֶת יְרוּשָׁלַיִם לְעִיִּים: אֱלֹהִים, זֵדִים קָמוּ עָלֵינוּ, וַעֲדַת עָרִיצִים בִּקְשׁוּ נַפְשֵׁנוּ, וְלֹא שָׂמוּךָ לְנֶגְדָּם:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"כְּרַחֵם אָב עַל בָּנִים, כֵּן תְּרַחֵם יהוה עָלֵינוּ. לַיהוה הַיְּשׁוּעָה, עַל עַמְּךָ בִרְכָתֶךָ סֶּלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶּלָה: יהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֶבֶן הָרֹאשָׁה, לְעִיִּים וְלַחֲרִישָׁה, וְנוֹחֲלֵי מוֹרָשָׁה, מְנוֹד רֹאשׁ בַּלְאֻמִים. בְּקִרְבִּי לֵב נִכְאָב, נִדְוֶה וְנִדְאָב, נִשְׁאַרְנוּ כְּאֵין אָב, וְהָיִינוּ כִּיתוֹמִים. רַכָּה וַעֲנֻגָּה, בַּשּׁוֹשַׁנִּים סוּגָה, וְעַתָּה הִיא נוּגָה, מְסוּרָה בְּיַד קָמִים. הָיְתָה כְּאַלְמָנָה, קִרְיָה נֶאֱמָנָה, וְזֶרַע מִי מָנָה, נִמְכְּרוּ בְּלֹא דָּמִים. מְעֻנָּגָה וְרַכָּה, צָלְחָה לִמְלוּכָה, וּמַעֲנִיתָהּ אָרְכָה, זֶה כַּמֶּה שָׁנִים וְיָמִים. בֵּית יַעֲקֹב לְבִזָּה, לְלַעַג וּלְעִזָּה, הָעִיר הָעַלִּיזָה, לְמַטָּעֵי כְרָמִים. רְווּיָה תַרְעֵלָה, בְּיַד בְּנֵי עַוְלָה, הָרְצוּיָה כְעוֹלָה, וְכִקְטֹרֶת הַסַּמִּים. מָאֲסָה לִזְנֹחַ, תּוֹרַת אֲבִי זָנוֹחַ, וְלֹא מָצְאָה מָנוֹחַ, לֵילוֹת וְגַם יָמִים. נוֹרָא אֵל עֶלְיוֹן, מִמְּךָ יְהִי צִבְיוֹ,. לְהָשִׁיב לְרִיב צִיּוֹן, שְׁנַת שִׁלּוּמִים. חַדֵּשׁ יָמֵינוּ כְּקֶדֶם, מְעוֹנָה אֱלֹהֵי קֶדֶם, וְלַבֵּן כַּצֶּמֶר אֹדֶם, וְכַשֶּׁלֶג כְּתָמִים. חַזְּקֵנוּ בְּיִרְאָתֶךָ, וּבְקִיּוּם תּוֹרָתֶךָ, וּפָקְדֵנוּ בִּישׁוּעָתֶךָ, אֵל מָלֵא רַחֲמִים.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, מִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לְחַטָּאִים, וּסְלִיחָה לְפוֹשְׁעִים. עֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וָרוּחַ, לֹא כְרָעָתָם תִּגְמֹל. אֵל, הוֹרֵיתָ לָּנוּ לוֹמַר שְׁלֹשׁ עֶשְׂרֵה, וּזְכָר לָנוּ הַיּוֹם בְּרִית שְׁלשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָיו מִקֶּדֶם, כְּמוֹ שֶׁכָּתוּב: וַיֵּרֶד יהוה בֶּעָנָן, וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם, יהוה:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"פזמון. שליח הציבור אומר את הבית הראשון, והקהל חוזר אחריו, ולאחר מכן כל בית הקהל אומר ושליח הציבור חוזר.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי, גָּדְלוּ וְהִצְלִיחוּ וְגַם עָשׂוּ פֶרִי, וּמֵעֵת הֻדָּחוּ וְהָלְכוּ עִמּוֹ קֶרִי, הָיוּ הָלוֹךְ וְחָסוֹר עַד הַחֹדֶשׁ הָעֲשִׂירִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"בָּעֲשִׂירִי לַחֹדֶשׁ סָמַךְ מֶלֶךְ בָּבֶל, וְצָר עַל עִיר הַקֹּדֶשׁ וְנִקְרַב רַב הַחוֹבֵל, נֻתַּתִּי הָדֵשׁ וְעֻנֵּיתִי בַכֶּבֶל, וְהָיָה מִדֵּי חֹדֶשׁ לְאֵבֶל כִּנּוֹרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"רֵאשִׁית בִּכּוּרָה לְרֵאשִׁית הַחֵרֶם, שֵׁם אֲחֵרִים הִזְכִּירָה וְהֶעָוׂן גּוֹרֵם, פְּנֵי אֵל לֹא הִכִּירָה וְשֻׁטְּפָה בְזֶרֶם, צָרָה כְּמַבְכִּירָה כָּעֵת בַּמָּרוֹם תַּמְרִיא.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"הָאֱלֹהִים הֵבִיא יוֹם רָעָה וּמָצוֹר, צִוָּה צָרַי סְבִיבִי עוֹלָלַי לִבְצוֹר, יוֹם הֵרַךְ לְבָבִי וְאֵין כֹּחַ לַעֲצֹר, וְדִבֶּר אֶל נָבִיא מְשֹׁל אֶל בֵּית הַמֶּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"מִיּוֹשְׁבֵי שַׁעַר הֶעֱבִיר אַדֶּרֶת, חֲמָתוֹ כָּאֵשׁ בָּעַר וְהֵרִים עֲטֶרֶת, וּמִלְּבָנוֹן יַעַר הִשְׁלִיךְ תִּפְאֶרֶת, וְרוּחַ סוֹעָה וָסַעַר תְּסַמֵּר שַׂעֲרַת בְּשָׂרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"יָפְיָפִית נִמְשַׁלְתְּ וְעַתָּה קְדוֹרַנִּית, בְּעָוׂן כִּי כָשַׁלְתְּ וְלִבֵּךְ אֲחוֹרַנִּית, זִנְּבוּךְ וְנֶחֱשַׁלְתְּ רִאשׁוֹנָה וְשֵׁנִית, וְהָחְתֵּל לֹא חֻתַּלְתְּ מְעַט צֳרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"צַדִּיק הַצּוּר תָּם נְשֹׂא עָוׂן נִלְאָה, מִכְּרוּב לְמִפְתָּן לְפִנַּת גַּג דָּאָה, מֵעָוׂן הַנִּכְתָּם וְצַעֲקָתָם בָּאָה, רַבָּה רָעָתָם כְּעֵץ עֹשֶׂה פֶּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"חִזֵּק כָּל קָמַי תּוֹכֵן הָעֲלִילוֹת, כִּי מָלְאוּ יָמַי בְּרֹעַ מִפְעָלוֹת, וּמִבֹּשֶׁת עֲלוּמַי שָׁכַחְתִּי גְמוּלוֹת, נוֹתֵן לַחְמִי וּמֵימַי פִּשְׁתִּי וְצַמְרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"קָמַי פִּיהֶם פָּעֲרוּ וְנַחֲלָתִי בִּלֵּעוּ, מְאֹד עָלַי גָּבָרוּ וְדָמִי שָׁתוּ וְלָעוּ, נָכְרִים עָלַי צָרוּ וְאֶת אַחַי הֵרֵעוּ, הָאוֹמְרִים עָרוּ עָרוּ בְּנֵי שֵׂעִיר הַחוֹרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אָמְרוּ לְכוּ נְכַלֵּם וְנַשְׁבִּיתָה זִכְרָם, אֵל קַנֹּא וְנוֹקֵם גָּמְלֵם יִשְׂאוּ אֶת שִׁבְרָם, כְּמַעֲשֵׂיהֶם שַׁלֵּם וְיֵבֹשׁוּ מִשִּׂבְרָם, כְּאִישׁ חֲלוֹם חוֹלֵם שְׁלֹשָׁה סַלֵּי חוֹרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"פִּצְעִי לֹא רֻכָּכָה וְחַבּוּרוֹתַי רֶצַח, וְעֵינִי הֻכְהָתָה צוֹפָה לְדוֹדִי צַח, הַעוֹד לֹא שָׁכָכָה חֲמָתוֹ לָנֶצַח, עַל מֶה עָשָׂה כָּכָה וּמֶה חֳרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"רַחוּם זֶה אֵלִי אַל לָעַד תִּזְנַח, אָרְכוּ יְמֵי אֶבְלִי וְעוֹד לִבִּי נֶאֱנַח, שׁוּבָה אֵל לְאָהֳלִי מְקוֹמְךָ אַל תַּנַּח, שַׁלֵּם יְמֵי אֶבְלִי כִּי תָבוֹא עַל שְׂכָרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"יהוה מְנָת חֶלְקִי חוּשָׁה לִּי לְעֶזְרָה, וּפִתַּחְתָּ שַׂקִּי שִׂמְחָה לִי לְאַזְּרָה, וְתַגִּיהַּ אֶת חָשְׁכִּי בְּאוֹרְךָ לְהָאִירָה, אֶת נֶשֶׁף חִשְׁקִי כִּי אַתָּה נֵרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"מִיָּגוֹן וַאֲנָחָה פְּדֵה אֵל אֶת נַפְשִׁי, עֲשֵׂה לְעַמְּךָ הֲנָחָה מַלְכִּי וּקְדוֹשִׁי, תַּהֲפוֹךְ לִרְוָחָה אֶת צוֹם הַחֲמִישִׁי, לְשָׂשׂוֹן וּלְשִׂמְחָה צוֹם הָרְבִיעִי וְצוֹם הָעֲשִׂירִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, מִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לְחַטָּאִים, וּסְלִיחָה לְפוֹשְׁעִים. עֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וָרוּחַ, לֹא כְרָעָתָם תִּגְמֹל. אֵל, הוֹרֵיתָ לָּנוּ לוֹמַר שְׁלֹשׁ עֶשְׂרֵה, וּזְכָר לָנוּ הַיּוֹם בְּרִית שְׁלשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָיו מִקֶּדֶם, כְּמוֹ שֶׁכָּתוּב: וַיֵּרֶד יהוה בֶּעָנָן, וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם, יהוה:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"זְכֹר רַחֲמֶיךָ יהוה וַחֲסָדֶיךָ, כִּי מֵעוֹלָם הֵמָּה: זָכְרֵנוּ יהוה בִּרְצוֹן עַמֶּךָ, פָּקְדֵנוּ בִּישׁוּעָתֶךָ. זְכֹר עֲדָתְךָ קָנִיתָ קֶדֶם, גָּאַלְתָּ שֵׁבֶט נַחֲלָתֶךָ, הַר צִיּוֹן זֶה שָׁכַנְתָּ בּוֹ: זְכֹר יהוה חִבַּת יְרוּשָׁלָיִם, אַהֲבַת צִיּוֹן אַל תִּשְׁכַּח לָנֶצַח. אַתָּה תָקוּם תְּרַחֵם צִיּוֹן, כִּי עֵת לְחֶנְנָהּ, כִּי בָא מוֹעֵד: זְכֹר יהוה לִבְנֵי אֱדוֹם אֵת יוֹם יְרוּשָׁלָיִם, הָאוֹמְרִים עָרוּ עָרוּ, עַד הַיְסוֹד בָּהּ: זְכֹר לְאַבְרָהָם לְיִצְחָק וּלְיִשְׂרָאֵל עֲבָדֶיךָ, אֲשֶׁר נִשְׁבַּעְתָּ לָהֶם בָּךְ, וַתְּדַבֵּר אֲלֵהֶם, אַרְבֶּה אֶת זַרְעֲכֶם כְּכוֹכְבֵי הַשָּׁמַיִם, וְכָל הָאָרֶץ הַזֹּאת אֲשֶׁר אָמַרְתִּי אֶתֵּן לְזַרְעֲכֶם, וְנָחֲלוּ לְעוֹלָם: זְכֹר לַעֲבָדֶיךָ לְאַבְרָהָם לְיִצְחָק וּלְיַעֲקֹב, אַל תֵּפֶן אֶל קְשִׁי הָעָם הַזֶּה וְאֶל רִשְׁעוֹ וְאֶל חַטָּאתוֹ:\n\nאַל נָא תָשֵׁת עָלֵינוּ חַטָּאת אֲשֶׁר נוֹאַלְנוּ וַאֲשֶׁר חָטָאנוּ: חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"יש המוסיפים פיוט זה ואומרים אותו בית בית עם שליח הציבור:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אֵל נָא, רְפָא נָא תַּחֲלוּאֵי גֶפֶן פּוֹרִיָּה, בּוֹשָׁה וַחֲפוּרָה וְאֻמְלַל פִּרְיָהּ, גְּאָלֶנָּה מִשַּׁחַת וּמִמַּכָּה טְרִיָּה, עֲנֵנוּ כְּשֶׁעָנִיתָ לְאַבְרָהָם אָבִינוּ בְּהַר הַמּוֹרִיָּה.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"דִּגְלֵי עָם פְּדוּיֵי בִּזְרוֹעַ חָשׂוּף, הַצֵּל מִנֶּגֶף וְאַל יִהְיוּ לְשִׁסּוּף, וְתַעֲנֶה קְרִיאָתֵנוּ וּלְמַעֲשֵׂה יָדֶיךָ תִּכְסֹף, עֲנֵנוּ כְּשֶׁעָנִיתָ לַאֲבוֹתֵינוּ עַל יַם סוּף.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"זְכוּת צוּר חֻצַּב הַיּוֹם לָנוּ תְגַל, חָשְׂכֵנוּ מֵאֶנֶף וּנְחֵנוּ בְּיֹשֶׁר מַעְגָּל, טַהֵר טֻמְאָתֵנוּ וְלִמְאוֹר תּוֹרָתְךָ עֵינֵינוּ גַל, עֲנֵנוּ כְּשֶׁעָנִיתָ לִיהוֹשֻׁעַ בַּגִּלְגָּל.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"יָהּ, רְאֵה דֶשֶׁן עָקוּד וְהַצְמַח לָנוּ תְרוּפָה, כַּלֵּה שׁוֹד וָשֶׁבֶר, סַעַר וְסוּפָה, לַמְּדֵנוּ וְחַכְּמֵנוּ אִמְרָתְךָ הַצְּרוּפָה, עֲנֵנוּ כְּשֶׁעָנִיתָ לִשְׁמוּאֵל בַּמִּצְפָּה.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"מֻתְמָם מֵרֶחֶם שָׁרָשָׁיו אַל תַּקְמֵל, נַקֵּנוּ מִכֶּתֶם וְשֶׁמֶץ וְלֹא נֵאָמֵל, סְעָדֵנוּ וְנִוָּשֵׁעָה וְאָרְחוֹת חֲסָדֶיךָ נִגָּמֵל, עֲנֵנוּ כְּשֶׁעָנִיתָ לְאֵלִיָּהוּ בְּהַר הַכַּרְמֶל.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"עוֹדְדֵנוּ בְּצֶדֶק מָשׁוּי מִמַּיִם וְכַפֵּר זָדוֹן וּמְשׁוּגָה, פְּדֵנוּ מִמְּהוּמַת מָוֶת וְאָחוֹר בַּל נִסּוֹגָה, צַוֵּה יְשׁוּעָתֵנוּ וּבַעֲוׂנוֹתֵינוּ אַל נִתְמוֹגְגָה, עֲנֵנוּ כְּשֶׁעָנִיתָ לְיוֹנָה בִּמְעֵי הַדָּגָה.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"קְדֻשַּׁת אִישׁ חֲסִידֶךָ זְכֹר לִיפַת פַּעֲמַיִם, רַחֲמֶיךָ תְּעוֹרֵר כִּי לָקִינוּ בְּכִפְלַיִם, שׁוּבֵנוּ תֹּקֶף לְיִרְאָתֶךָ וְלֹא נֵחָשֵׂף שׁוּלַיִם, עֲנֵנוּ כְּשֶׁעָנִיתָ לְדָוִד וְלִשְׁלֹמֹה בְנוֹ בִּירוּשָׁלַיִם.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"בתענית אסתר יש מוסיפים:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"תַּעֲנֶה לְקוֹרְאֶיךָ וְהַסְכֵּת מִמְּעוֹנִים, תִּשְׁמַע שַׁוְעַת צוֹעֲקֶיךָ, שׁוֹמֵעַ אֶל אֶבְיוֹנִים, תְּרַחֵם עַל בָּנֶיךָ כְּרַחֵם אָב עַל בָּנִים, עֲנֵנוּ כְּמוֹ שֶׁעָנִיתָ לְמָרְדְּכַי וְאֶסְתֵּר, וְתָלוּ עַל עֵץ חֲמִשִּׁים הָאָב עִם הַבָּנִים.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"מכאן כולם אומרים:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"זְכֹר לָנוּ בְּרִית אָבוֹת כַּאֲשֶׁר אָמַרְתָּ: וְזָכַרְתִּי אֶת בְּרִיתִי יַעֲקוֹב וְאַף אֶת בְּרִיתִי יִצְחָק וְאַף אֶת בְּרִיתִי אַבְרָהָם אֶזְכֹּר, וְהָאָרֶץ אֶזְכֹּר:\n\nזְכֹר לָנוּ בְּרִית רִאשׁוֹנִים כַּאֲשֶׁר אָמַרְתָּ: וְזָכַרְתִּי לָהֶם בְּרִית רִאשׁוֹנִים אֲשֶׁר הוֹצֵאתִי אוֹתָם מֵאֶרֶץ מִצְרַיִם לְעֵינֵי הַגּוֹיִם לִהְיוֹת לָהֶם לֵאלֹהִים, אֲנִי יהוה:\n\nעֲשֵׂה עִמָּנוּ כְּמָה שֶׁהִבְטַחְתָּנוּ: וְאַף גַּם זֹאת בִּהְיוֹתָם בְּאֶרֶץ אוֹיְבֵיהֶם לֹא מְאַסְתִּים וְלֹא גְעַלְתִּים לְכַלּוֹתָם לְהָפֵר בְּרִיתִי אִתָּם, כִּי אֲנִי יהוה אֱלֹהֵיהֶם: הָשֵׁב שְׁבוּתֵנוּ וְרַחֲמֵנוּ כְּמָה שֶׁכָּתוּב: וְשָׁב יהוה אֱלֹהֶיךָ אֶת שְׁבוּתְךָ וְרִחֲמֶךָ, וְשָׁב וְקִבֶּצְךָ מִכָּל הָעַמִּים אֲשֶׁר הֱפִיצְךָ יהוה אֱלֹהֶיךָ שָׁמָּה: קַבֵּץ נִדָּחֵינוּ כְּמָה שֶׁכָּתוּב: אִם יִהְיֶה נִדַּחֲךָ בִּקְצֵה הַשָּׁמָיִם, מִשָּׁם יְקַבֶּצְךָ יהוה אֱלֹהֶיךָ וּמִשָּׁם יִקָּחֶךָ: מְחֵה פְשָׁעֵינוּ כָּעָב וְכֶעָנָן כְּמָה שֶׁכָּתוּב: מָחִיתִי כָעָב פְּשָׁעֶיךָ וְכֶעָנָן חַטֹּאתֶיךָ, שׁוּבָה אֵלַי כִּי גְאַלְתִּיךָ: מְחֵה פְשָׁעֵינוּ לְמַעַנְךָ כַּאֲשֶׁר אָמַרְתָּ: אָנֹכִי אָנֹכִי הוּא מֹחֶה פְשָׁעֶיךָ לְמַעֲנִי, וְחַטֹּאתֶיךָ לֹא אֶזְכֹּר: הַלְבֵּן חֲטָאֵינוּ כַּשֶּׁלֶג וְכַצֶּמֶר כְּמָה שֶׁכָּתוּב: לְכוּ נָא וְנִוָּכְחָה יֹאמַר יהוה, אִם יִהְיוּ חֲטָאֵיכֶם כַּשָּׁנִים כַּשֶּׁלֶג יַלְבִּינוּ, אִם יַאְדִּימוּ כַתּוֹלָע כַּצֶּמֶר יִהְיוּ: זְרֹק עָלֵינוּ מַיִם טְהוֹרִים וְטַהֲרֵנוּ כְּמָה שֶׁכָּתוּב: וְזָרַקְתִּי עֲלֵיכֶם מַיִם טְהוֹרִים וּטְהַרְתֶּם, מִכֹּל טֻמְאֹתֵיכֶם וּמִכָּל גִּלּוּלֵיכֶם אֲטַהֵר אֶתְכֶם: רַחֵם עָלֵינוּ וְאַל תַּשְׁחִיתֵנוּ כְּמָה שֶׁכָּתוּב: כִּי אֵל רַחוּם יהוה אֱלֹהֶיךָ, לֹא יַרְפְּךָ וְלֹא יַשְׁחִיתֶךָ, וְלֹא יִשְׁכַּח אֶת בְּרִית אֲבֹתֶיךָ אֲשֶׁר נִשְׁבַּע לָהֶם: מוֹל אֶת לְבָבֵנוּ לְאַהֲבָה אֶת שְׁמֶךָ כְּמָה שֶׁכָּתוּב: וּמָל יהוה אֱלֹהֶיךָ אֶת לְבָבְךָ וְאֶת לְבַב זַרְעֶךָ, לְאַהֲבָה אֶת יהוה אֱלֹהֶיךָ בְּכָל לְבָבְךָ וּבְכָל נַפְשְׁךָ, לְמַעַן חַיֶּיךָ: הִמָּצֵא לָנוּ בְּבַקָּשָׁתֵנוּ כְּמָה שֶׁכָּתוּב: וּבִקַּשְׁתֶּם מִשָּׁם אֶת יהוה אֱלֹהֶיךָ וּמָצָאתָ, כִּי תִדְרְשֶׁנּוּ בְּכָל לְבָבְךָ וּבְכָל נַפְשֶׁךָ: תְּבִיאֵנוּ אֶל הַר קָדְשֶׁךָ וְשַׂמְּחֵנוּ בְּבֵית תְּפִלָּתֶךָ כְּמָה שֶׁכָּתוּב: וַהֲבִיאוֹתִים אֶל הַר קָדְשִׁי וְשִׂמַּחְתִּים בְּבֵית תְּפִלָּתִי, עוֹלוֹתֵיהֶם וְזִבְחֵיהֶם לְרָצוֹן עַל מִזְבְּחִי, כִּי בֵיתִי, בֵּית תְּפִלָּה יִקָּרֵא לְכָל הָעַמִּים:","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"פותחים את ארון הקודש ואמורים משפט משפט. יש קהילות בהם סדר המשפטים שונה וברוב הקהילות מדלגים על המשפט \"יהיו לרצון\".","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"שְׁמַע קוֹלֵנוּ, יהוה אֱלֹהֵינוּ, חוּס וְרַחֵם עָלֵינוּ, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ. הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם: אֲמָרֵינוּ הַאֲזִינָה יהוה, בִּינָה הֲגִיגֵנוּ. יִהְיוּ לְרָצוֹן אִמְרֵי פִינוּ וְהֶגְיוֹן לִבֵּנוּ לְפָנֶיךָ, יהוה צוּרֵנוּ וְגוֹאֲלֵנוּ. אַל תַּשְׁלִיכֵנוּ מִלְּפָנֶיךָ, וְרוּחַ קָדְשְׁךָ אַל תִּקַּח מִמֶּנּוּ. אַל תַּשְׁלִיכֵנוּ לְעֵת זִקְנָה, כִּכְלוֹת כֹּחֵנוּ אַל תַּעַזְבֵנוּ.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"מכאן מפסיקים לומר עם החזן בקול.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אַל תַּעַזְבֵנוּ יהוה, אֱלֹהֵינוּ אַל תִּרְחַק מִמֶּנוּ. עֲשֵׂה עִמָּנוּ אוֹת לְטוֹבָה, וְיִרְאוּ שׂוֹנְאֵינוּ וְיֵבוֹשׁוּ, כִּי אַתָּה יהוה עֲזַרְתָּנוּ וְנִחַמְתָּנוּ. כִּי לְךָ יהוה הוֹחָלְנוּ, אַתָּה תַעֲנֶה אֲדֹנָי אֱלֹהֵינוּ.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"סוגרים את ארון הקודש.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, תָּבוֹא לְפָנֶיךָ תְּפִלָּתֵנוּ וְאַל תִּתְעַלַּם מִתְּחִנָּתֵנוּ, שֶׁאֵין אָנוּ עַזֵּי פָנִים וּקְשֵׁי עֹרֶף לוֹמַר לְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ צַדִּיקִים אֲנַחְנוּ וְלֹא חָטָאנוּ, אֲבָל אֲנַחְנוּ וַאֲבוֹתֵינוּ חָטָאנוּ.\nאָשַׁמְנוּ, בָּגַדְנוּ, גָּזַלְנוּ, דִּבַּרְנוּ דֹפִי. הֶעֱוִינוּ, וְהִרְשַׁענוּ, זַדְנוּ, חָמַסְנוּ, טָפַלְנוּ שֶׁקֶר. יָעַצְנוּ רָע, כְּזַּבְנוּ, לַצְנוּ, מָרַדְנוּ, נִאַצְנוּ, סָרַרְנוּ, עָוְינוּ, פָּשַׁעְנוּ, צָרַרְנוּ, קִשִּׁינוּ עֹרֶף. רָשַׁעְנוּ, שִׁחַתְנוּ, תִּעַבְנוּ, תָּעִינוּ, תִּעְתַּעְנוּ.\nסַרְנוּ מִמִּצְוׂתֶיךָ וּמִמִּשְׁפָּטֶיךָ הַטּוֹבִים וְלֹא שָׁוָה-לָנוּ. וְאַתָּה צַדִּיק עַל כָּל הַבָּא עָלֵינוּ, כִּי אֱמֶת עָשִׂיתָ, וַאֲנַחְנוּ הִרְשָׁעְנוּ:\n\nהִרְשַׁעְנוּ וּפָשַׁעְנוּ לָכֵן לֹא נוֹשָׁעְנוּ. וְתֵן בְּלִבֵּנוּ לַעֲזֹב דֶּרֶךְ רֶשַׁע, וְחִישׁ לָנוּ יֶשַׁע, כַּכָּתוּב עַל יַד נְבִיאֶךָ: יַעֲזוֹב רָשָׁע דַּרְכּוֹ וְאִישׁ אָוֶן מַחְשְׁבֹתָיו, וְיָשֹׁב אֶל יהוה וִירַחֲמֵהוּ, וְאֶל אֱלֹהֵינוּ כִּי יַרְבֶּה לִסְלוֹחַ:\n\nמְשִׁיחַ צִדְקֶךָ אָמַר לְפָנֶיךָ: שְׁגִיאוֹת מִי יָבִין מִנִּסְתָּרוֹת נַקֵּנִי: נַקֵּנוּ יהוה אֱלֹהֵינוּ מִכָּל פְּשָׁעֵינוּ וְטַהֲרֵנוּ מִכָּל טֻמְאוֹתֵינוּ, וּזְרֹק עָלֵינוּ מַיִם טְהוֹרִים וְטַהֲרֵנוּ, כַּכָּתוּב עַל יַד נְבִיאֶךָ: וְזָרַקְתִּי עֲלֵיכֶם מַיִם טְהוֹרִים וּטְהַרְתֶּם, מִכֹּל טֻמְאוֹתֵיכֶם וּמִכָּל גִּלּוּלֵיכֶם אֲטַהֵר אֶתְכֶם: עַמְּךָ וְנַחֲלָתְךָ רְעֵבֵי טוּבְךָ, צְמֵאֵי חַסְדְּךָ, תְּאֵבֵי יִשְׁעֶךָ. יַכִּירוּ וְיֵדְעוּ כִּי לַיהוה אֱלֹהֵינוּ הָרַחֲמִים וְהַסְּלִיחוֹת.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אם אין אומרים תחנון מדלגים על המשך הסליחות.","cond":["shacharitTachanun","10tevet","shacharitTachanun"]},{"kind":"text","text":"אֵל רַחוּם שְׁמֶךָ. אֵל חַנּוּן שְׁמֶךָ. בָּנוּ נִקְרָא שְׁמֶךָ. יהוה עֲשֵׂה לְמַעַן שְׁמֶךָ. עֲשֵׂה לְמַעַן אֲמִתָּךְ. עֲשֵׂה לְמַעַן בְּרִיתָךְ. עֲשֵׂה לְמַעַן גָּדְלָךְ וְתִפְאַרְתָּךְ. עֲשֵׂה לְמַעַן דָּתָךְ. עֲשֵׂה לְמַעַן הוֹדָךְ. עֲשֵׂה לְמַעַן וִעוּדָךְ. עֲשֵׂה לְמַעַן זִכְרָךְ. עֲשֵׂה לְמַעַן חַסְדָּךְ. עֲשֵׂה לְמַעַן טוּבָךְ. עֲשֵׂה לְמַעַן יִחוּדָךְ. עֲשֵׂה לְמַעַן כְּבוֹדָךְ. עֲשֵׂה לְמַעַן לִמּוּדָךְ. עֲשֵׂה לְמַעַן מַלְכוּתָךְ. עֲשֵׂה לְמַעַן נִצְחָךְ. עֲשֵׂה לְמַעַן סוֹדָךְ. עֲשֵׂה לְמַעַן עֻזָּךְ. עֲשֵׂה לְמַעַן פְּאֵרָךְ. עֲשֵׂה לְמַעַן צִדְקָתָךְ. עֲשֵׂה לְמַעַן קְדֻשָׁתָךְ. עֲשֵׂה לְמַעַן רַחֲמֶיךָ הָרַבִּים. עֲשֵׂה לְמַעַן שְׁכִינָתָךְ. עֲשֵׂה לְמַעַן תְּהִלָּתָךְ. עֲשֵׂה לְמַעַן אוֹהֲבֶיךָ שׁוֹכְנֵי עָפָר. עֲשֵׂה לְמַעַן אַבְרָהָם יִצְחָק וְיַעֲקֹב. עֲשֵׂה לְמַעַן מֹשֶׁה וְאַהֲרֹן. עֲשֵׂה לְמַעַן דָּוִד וּשְׁלֹמֹה. עֲשֵׂה לְמַעַן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ. עֲשֵׂה לְמַעַן צִיּוֹן מִשְׁכַּן כְּבוֹדֶךָ. עֲשֵׂה לְמַעַן שִׁמְמוֹת הֵיכָלֶךָ. עֲשֵׂה לְמַעַן הֲרִיסוּת מִזְבְּחֶךָ. עֲשֵׂה לְמַעַן הֲרוּגִים עַל שֵׁם קָדְשֶׁךָ. עֲשֵׂה לְמַעַן טְבוּחִים עַל יִחוּדֶךָ. עֲשֵׂה לְמַעַן בָּאֵי בָאֵשׁ וּבַמַּיִם עַל קִדּוּשׁ שְׁמֶךָ. עֲשֵׂה לְמַעַן יוֹנְקֵי שָׁדַיִם שֶׁלֹּא חָטְאוּ. עֲשֵׂה לְמַעַן גְּמוּלֵי חָלָב שֶׁלֹּא פָשְׁעוּ. עֲשֵׂה לְמַעַן תִּינוֹקוֹת שֶׁל בֵּית רַבָּן. עֲשֵׂה לְמַעַנְךָ אִם לֹא לְמַעֲנֵנוּ. עֲשֵׂה לְמַעַנְךָ וְהוֹשִׁיעֵנוּ.\n\nעֲנֵנוּ יהוה עֲנֵנוּ. עֲנֵנוּ אֱלֹהֵינוּ עֲנֵנוּ. עֲנֵנוּ אָבִינוּ עֲנֵנוּ. עֲנֵנוּ בּוֹרְאֵנוּ עֲנֵנוּ. עֲנֵנוּ גּוֹאֲלֵנוּ עֲנֵנוּ. עֲנֵנוּ דּוֹרְשֵׁנוּ עֲנֵנוּ. עֲנֵנוּ הָאֵל הַנֶּאֱמָן עֲנֵנוּ. עֲנֵנוּ וָתִיק וְחָסִיד עֲנֵנוּ. עֲנֵנוּ זַךְ וְיָשָׁר עֲנֵנוּ. עֲנֵנוּ חַי וְקַיָּם עֲנֵנוּ. עֲנֵנוּ טוֹב וּמֵטִיב עֲנֵנוּ. עֲנֵנוּ יוֹדֵעַ יֶצֶר עֲנֵנוּ. עֲנֵנוּ כּוֹבֵשׁ כְּעָסִים עֲנֵנוּ. עֲנֵנוּ לוֹבֵשׁ צְדָקוֹת עֲנֵנוּ. עֲנֵנוּ מֶלֶךְ מַלְכֵי הַמְּלָכִים עֲנֵנוּ. עֲנֵנוּ נוֹרָא וְנִשְׂגָּב עֲנֵנוּ. עֲנֵנוּ סוֹלֵחַ וּמוֹחֵל עֲנֵנוּ. עֲנֵנוּ עוֹנֶה בְּעֵת צָרָה עֲנֵנוּ. עֲנֵנוּ פּוֹדֶה וּמַצִּיל עֲנֵנוּ. עֲנֵנוּ צַדִּיק וְיָשָׁר עֲנֵנוּ. עֲנֵנוּ קָרוֹב לְקוֹרְאָיו עֲנֵנוּ. עֲנֵנוּ רַחוּם וְחַנוּן עֲנֵנוּ. עֲנֵנוּ שׁוֹמֵעַ אֶל אֶבְיוֹנִים עֲנֵנוּ. עֲנֵנוּ תּוֹמֵךְ תְּמִימִים עֲנֵנוּ. עֲנֵנוּ אֱלֹהֵי אֲבוֹתֵינוּ עֲנֵנוּ. עֲנֵנוּ אֱלֹהֵי אַבְרָהָם עֲנֵנוּ. עֲנֵנוּ פַּחַד יִצְחָק עֲנֵנוּ. עֲנֵנוּ אֲבִיר יַעֲקֹב עֲנֵנוּ. עֲנֵנוּ עֶזְרַת הַשְּׁבָטִים עֲנֵנוּ. עֲנֵנוּ מִשְׂגַּב אִמָּהוֹת עֲנֵנוּ. עֲנֵנוּ קָשֶׁה לִכְעוֹס עֲנֵנוּ. עֲנֵנוּ רַךְ לִרְצוֹת עֲנֵנוּ. עֲנֵנוּ עוֹנֶה בְּעֵת רָצוֹן עֲנֵנוּ. עֲנֵנוּ אֲבִי יְתוֹמִים עֲנֵנוּ. עֲנֵנוּ דַּיַּן אַלְמָנוֹת עֲנֵנוּ.\n\nמִי שֶׁעָנָה לְאַבְרָהָם אָבִינוּ בְּהַר הַמּוֹרִיָּה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְיִצְחָק בְּנוֹ כְּשֶׁנֶּעֱקַד עַל גַּבֵּי הַמִּזְבֵּחַ הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְיַעֲקֹב בְּבֵית אֵל הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְיוֹסֵף בְּבֵית הָאֲסוּרִים הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לַאֲבוֹתֵינוּ עַל יַם סוּף הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְמֹשֶׁה בְּחוֹרֵב הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְאַהֲרֹן בַּמַּחְתָּה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְפִינְחָס בְּקוּמוֹ מִתּוֹךְ הָעֵדָה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לִיהוֹשֻׁעַ בַּגִּלְגָּל הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לִשְׁמוּאֵל בַּמִּצְפָּה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְדָוִד וּשְׁלֹמֹה בְנוֹ בִּירוּשָׁלָיִם הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְאֵלִיָּהוּ בְּהַר הַכַּרְמֶל הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לֶאֱלִישָׁע בִּירִיחוֹ הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְיוֹנָה בִּמְעֵי הַדָּגָה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְחִזְקִיָּהוּ מֶלֶךְ יְהוּדָה בְּחָלְיוֹ הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לַחֲנַנְיָה מִישָׁאֵל וַעֲזַרְיָה בְּתוֹךְ כִּבְשַׁן הָאֵשׁ הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְדָנִיֵּאל בְּגוֹב הָאֲרָיוֹת הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְמָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְעֶזְרָא בַּגּוֹלָה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְכָל הַצַּדִּיקִים וְהַחֲסִידִים וְהַתְּמִימִים וְהַיְּשָׁרִים הוּא יַעֲנֵנוּ.\n\nרַחֲמָנָא דְעָנֵי לַעֲנִיֵי עֲנֵינָא. רַחֲמָנָא דְעָנֵי לִתְבִירֵי לִבָּא עֲנֵינָן. רַחֲמָנָא דְעָנֵי לְמַכִּיכֵי רוּחָא עֲנֵינָן. רַחֲמָנָא עֲנֵינָן. רַחֲמָנָא חוּס. רַחֲמָנָא פְּרוֹק. רַחֲמָנָא שְׁזִיב. רַחֲמָנָא רְחַם עֲלָן. הַשְׁתָּא בַּעֲגָלָא וּבִזְמַן קָרִיב.","cond":["shacharitTachanun","10tevet","shacharitTachanun"]},{"kind":"header","text":"סליחות לתענית אסתר","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"סליחות לתענית אסתר","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"סְלַח לָנוּ אָבִינוּ כִּי בְּרֹב אִוַּלְתֵּנוּ שָׁגִינוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי רַבּוּ עֲוׂנֵינוּ.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"אֵל אֶרֶךְ אַפַּיִם אַתָּה וּבַעַל הָרַחֲמִים נִקְרֵאתָ, וְדֶרֶךְ תְּשׁוּבָה הוֹרֵיתָ, גְּדֻלַּת רַחֲמֶיךָ וַחֲסָדֶיךָ תִּזְכֹּר הַיּוֹם וּבְכָל יוֹם לְזֶרַע יְדִידֶיךָ. תֵּפֶן אֵלֵינוּ בְּרַחֲמִים, כִּי אַתָּה הוּא בַּעַל הָרַחֲמִים. בְּתַחֲנוּן וּבִתְפִלָּה פָּנֶיךָ נְקַדֵּם, כְּהוֹדַעתָּ לֶעָנָו מִקֶּדֶם. מֵחֲרוֹן אַפְּךָ שׁוּב, כְּמוֹ בְּתוֹרָתְךָ כָּתוּב. וּבְצֵל כְּנָפֶיךָ נֶחְסֶה וְנִתְלוֹנָן, כְּיוֹם וַיֵּרֶד יהוה בֶּעָנָן. תַּעֲבֹר עַל פֶּשַׁע וְתִמְחֶה אָשָׁם, כְּיוֹם וַיִּתְיַצֵּב עִמּוֹ שָׁם. תַּאֲזִין שַׁוְעָתֵנוּ וְתַקְשִׁיב מֶנּוּ מַאֲמָר, כְּיוֹם וַיִּקְרָא בְשֵׁם יהוה, וְשָׁם נֶאֲמַר:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"קַוּׂה קִוִּינוּ יהוה, וַיֵּט אֵלֵינוּ וַיּשְׁמַע שַׁוְעָתֵנוּ. אַף אֹרַח מִשְׁפָּטֶיךָ יהוה קִוִּינוּךָ, לְשִׁמְךָ וּלְזִכְרְךָ תַּאֲוַת נָפֶשׁ:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"כְּרַחֵם אָב עַל בָּנִים, כֵּן תְּרַחֵם יהוה עָלֵינוּ. לַיהוה הַיְּשׁוּעָה, עַל עַמְּךָ בִרְכָתֶךָ סֶּלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶּלָה: יהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"סְלַח נָא לַעֲוׂן הָעָם הַזֶּה כְּגֹדֶל חַסְדֶּךָ, וְכַאֲשֶׁר נָשָׂאתָה לָעָם הַזֶּה מִמִּצְרַיִם וְעַד הֵנָּה: וְשָׁם נֶאֱמַר:","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"קהל ואחריו שליח הציבור:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"וַיֹּאמֶר יהוה: סָלַחְתִּי כִּדְבָרֶךָ:\n\nהַטֵּה אֱלֹהַי אָזְנְךָ וּשֲׁמָע, פְּקַח עֵינֶיךָ וּרְאֵה שׁוֹמְמוֹתֵינוּ וְהָעִיר אֲשֶׁר נִקְרָא שִׁמְךָ עָלֶיהָ, כִּי לֹא עַל צִדְקוֹתֵינוּ אֲנַחְנוּ מַפִּילִים תַּחֲנוּנֵינוּ לְפָנֶיךָ, כִּי עַל רַחֲמֶיךָ הָרַבִּים: אֲדֹנָי שְׁמָעָה, אֲדֹנָי סְלָחָה, אֲדֹנָי הַקְשִׁיבָה וַעֲשֵׂה אַל תְּאַחַר, לְמַעַנְךָ אֱלֹהַי, כִּי שִׁמְךָ נִקְרָא עַל עִירְךָ וְעַל עַמֶּךָ:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אָדָם בְּקוּם עָלֵינוּ, חִיל אֲחָזַתְנוּ לִרְעֹד. בְּהִסְתַּפְּחוֹ לְמַלְכוּת חָנֵף, כִּמְעַט כָּשַׁלְנוּ לִמְעֹד. גָּמְרוּ לְמָכְרֵנוּ כְּתֵל וְחָרִיץ בְּלִי מִסְעוֹד, אָמְרוּ: לְכוּ וְנַכְחִידֵם מִגּוֹי וְלֹא יִזָּכֵר שֵׁם יִשְׂרָאֵל עוֹד: דַּלּוּ עֵינַי לַמָּרוֹם, קְרָאתִיךָ אוֹיְבַי לָקֹב. הַכְרֵת שֵׁם וּשְׁאָר, וּמְחֵה שֵׁם לִרְקֹב. וְצֹר צוֹרְרַי בְּנִכְלֵיהֶם אֲשֶׁר נִכְּלוּ לַעֲקֹב. וַיֹּאמְרוּ: לֹא יִרְאֶה יָהּ, וְלֹא יָבִין אֱלֹהֵי יַעֲקֹב: זְרוּיִים עִנָּה וַיַּגֶּה, וְלֹא מִלֵּב לְכַלּוֹתָם. חָבוּ לְפָנִים, וְרִדָּם בַּהֲסָרַת טַבַּעַת לְהַחֲלוֹתָם. טוֹב דְּבָרוֹ הֵקִים לְעֵינֵי הַגּוֹיִם לְהַעֲלוֹתָם. בְּאֶרֶץ אוֹיְבֵיהֶם לֹא מְאַסְתִּים וְלֹא גְעַלְתִּים לְכַלֹּתָם: יִדַּע רֶמֶז הַקּוֹרוֹת לְעַם מְעֻפָּר וּמְהֻדָּס. כְּתָב הַסְתֵּר אַסְתִּיר וּמָר דְּרוֹר מְפֻרְדָּס. לִשְׁבֹּת הָמָן מִמָּחֳרָת, הֲמִן הָעֵץ קֻנְדָּס. תַּחַת הַנַּעֲצוּץ יַעֲלֶה בְרוֹשׁ, וְתַחַת הַסִּרְפָּד יַעֲלֶה הֲדַס: מַקְשִׁיב דְּבַר שֶׁקֶר כָּתַב שִׂטְנָה וָעֶצֶב. נִתְעַטֵּף בְּבִגְדֵי שְׂרָד כְּטָעָה בְּמִנְיַן קֶצֶב. סָדַּר לְהִשְׁתַּמֵּשׁ בְּשׁוֹנִים כְּלֵי הַמַּחֲצֵב. וַיָּבוֹא גַם הַשָּׂטָן בְּתֹכָם לְהִתְיַצֵּב: עַם הַנִּמְצְאִים בְּשׁוּשָׁן, בְּאָכְלָם מִזֶּבַח עוֹכְרָם. פָּעַר פִּיו לְהַשְׂטִינָם, וּלְהַסְגִּירָם בְּיַד נוֹתֵן מִכְרָם. צוּר הִסְכִּים לִכְתֹּב אִגֶּרֶת לְאַבֵּד שִׂבְרָם. אָמַרְתִּי אַפְאֵיהֶם, אַשְׁבִּיתָה מֵאֱנוֹשׁ זִכְרָם: קְדוֹשִׁים מַלְאֲכֵי שָׁלוֹם מַר יִבְכָּיוּן בִּצְעָקָה. רַחוּם הַבֵּט לַבְּרִית וְאַל תָּפֵר לְהַרְחִיקָה. שָׁמְעָה מוֹרָשָׁה, וַתִּלְבַּשׁ בִּגְדֵי אַלְמְנוּת וּמוּעָקָה. וַתָּשֶׂם יָדָהּ עַל רֹאשָׁהּ, וַתֵּלֶךְ הָלוֹךְ וּזְעָקָה: תִּשְׁבִּי שָׂם אֵזוֹר שַׂק בְּמָתְנָיו תַּחְבֹּשֶׁת. מִהֵר וְהוֹדִיעַ יְשֵׁנֵי מַכְפֵּל, אָבוֹת שְׁלֹשֶׁת. נָחַץ לְרוֹעֶה, מַה לְּךָ נִרְדָּם לְהִתְעַשֵּׁת. קוּם קְרָא אֶל אֱלֹהֶיךָ אוּלַי יִתְעַשֵּׁת: חוֹתַם טִיט אֲשֶׁר נַעֲשָׂה, לְבִלְשָׁן סִפֵּר. מִנִּינְוֵה לָמְדוּ לְאַחַר גְּזֵרָה כַּעַס לְהָפֵר. בֶּן קִישׁ הִקִּישׁ דַּלְתוֹת בֵּית הַסֵּפֶר. וַיְּכַס שַׂק, וַיֵּשֶׁב עַל הָאֵפֶר: רִבֵּץ תִּינוֹקוֹת לְפָנָיו יָמִים שְׁלֹשָׁה, צָמִים וּמֻכְפָּנִים. בְּקוֹל יַעֲקֹב לַחֲלֹשׁ יְדֵי עַז פָּנִים. יָדָיו אֱמוּנָה לָאֵל, הַצִּילֵנִי נָא מֵעֶלְבּוֹנִים. פֶּן יָבוֹא וְהִכַּנִי אֵם עַל בָּנִים: מִזֶּה אֵלֶּה וּמִזֶּה אֵלֶּה, בְּנֵי אֵיתָנַי וְרַבָּנָי. כֻּלָּם צָעֲקוּ, וַתַּעַל שַׁוְעָתָם אֶל יהוה. יָהּ, לְקוֹל רִנּוּן כְּבוֹא, שָׁאַל לִפְנָי. וּמֶה קוֹל הַצֹּאן הַזֶּה בְּאָזְנָי: רוֹעֶה הֱשִׁיבוֹ, הֵם קְטַנֵּי קֹדֶשׁ זֶרַע. יָהּ, הַצֵּל לְקוּחִים לַמָּוֶת מֵאוֹיֵב הָרָע. חַנּוּן נִכְמְרוּ רַחֲמָיו וַיְּבַקֵּשׁ לִבְכּוֹת הַמְאֹרָע. וַיְּהִי כִּקְרֹא מֶלֶךְ יִשְׂרָאֵל אֶת הַסֵּפֶר, וַיִּקְרָע: יְהוּדִי הוֹקִיעַ, יְלָדָיו לְמַטָּה וַאֲבִיהֶם לְמַעְלָה. אִישׁ אִישׁ בְּשָׁלֹשׁ אַמּוֹת, וְהָרְבִיעִית אַוֵּיר מְגֻלָּה. מִשְׁנֶה נָקָם חָזָה, וְשָׂמַח וְשָׂח תְּהִלָּה. אֹתִי הֵשִׁיב עַל כַּנִּי וְאוֹתוֹ תָלָה: וַתִּכְתֹּב אֶסְתֵּר תֹּקֶף, לִקְרוֹת כִּבְהַלֵּל מְהוֹדִים. מִלְּמַעְלָה קִיְּמוּ מַה שֶּׁקִּבְּלוּ לְמַטָּה דּוֹדִים. נֵס יְנוֹסֵס לְפַרְסֵם כְּאָז פִּלְאוֹ מַסְהִידִים. בָּעֵת הַזֹּאת רֶוַח וְהַצָּלָה יַעֲמוֹד לַיְּהוּדִים:","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, מִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לְחַטָּאִים, וּסְלִיחָה לְפוֹשְׁעִים. עֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וָרוּחַ, לֹא כְרָעָתָם תִּגְמֹל. אֵל, הוֹרֵיתָ לָּנוּ לוֹמַר שְׁלֹשׁ עֶשְׂרֵה, וּזְכָר לָנוּ הַיּוֹם בְּרִית שְׁלשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָיו מִקֶּדֶם, כְּמוֹ שֶׁכָּתוּב: וַיֵּרֶד יהוה בֶּעָנָן, וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם, יהוה:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"כִּי עִמְּךָ מְקוֹר חַיִּים, בְּאוֹרְךָ נִרְאֶה אוֹר: בְּקָרְאֵנוּ עֲנֵנוּ אֱלֹהֵי צִדְקֵנוּ, בַּצָּר הִרְחַבְתָּ לָנוּ, חָנֵּנוּ וּשְׁמַע תְּפִלָּתֵנוּ. וְעַתָּה יִגְדַּל נָא כֹּחַ אֲדֹנָי, כַּאֲשֶׁר דִּבַּרְתָּ לֵאמֹר:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"כְּרַחֵם אָב עַל בָּנִים, כֵּן תְּרַחֵם יהוה עָלֵינוּ. לַיהוה הַיְּשׁוּעָה, עַל עַמְּךָ בִרְכָתֶךָ סֶּלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶּלָה: יהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אַתָּה הָאֵל עוֹשֵׂה פְלָאוֹת, בָּעַמִּים הוֹדַעְתָּ עֹז נוֹרָאוֹת, גָאַלְתָּ בִּזְרוֹעַ עַמְּךָ מִתְּלָאוֹת, דִּכִּיתָ צָרֵיהֶם בְּמוֹתֵי תַחֲלוּאוֹת. הָאוֹיֵב בְּקוּמוֹ לְעוֹרֵר מְדָנִים, וְדִמָּה לְהַכְרִית פִּרְחֵי עֲדָנִים, זָמַם לִשְׁקֹל לְגִנְזֵי אֲדוֹנִים, חֲלִיפֵי מְאַת כִּכְּרֵי אֲדָנִים. טְלָאֶיךָ הִזְהַרְתָּ שִׁקְלֵיהֶם לְהַקְדִּים, יָדַעְתָּ הָעֲתִידוֹת וְדָרַשְׁתָּ נִשְׁקָדִים, כִּבּוּי לְהַמְצִיא לְלַהַב יוֹקְדִים, לְקוּחִים לַמָּוֶת לְתֶחִי נִפְקָדִים. מַסֵּכָה צָרָה בְּעָבְדָם לְפָנִים, נִמְסְרוּ לְהָתֵז קְנוֹקְנוֹת וּגְפָנִים, סְבָבוּם מוֹקְשִׁים בְּכָל דְּפָנִים, עֵינֵיהֶם לְךָ תוֹלִים וּבְסִתְרְךָ נִצְפָּנִים. פּוּר נֶהְפַּךְ בְּאוֹיְבִים לִשְׁלֹט, צְלִיבָה הוּכַן אֲגָגִי לִקְלֹט, קַלַּע וּבַלַּע פְּנֵי הַלּוֹט הַלּוֹט, רִיבֵי עָם בְּאַשְׁמַנִּים לַעֲלֹט. שָׁלוֹם וֶאֱמֶת נִכְתַּב מִכָּל צַד, תֹּקֶף יֶשַׁע סֶלַע וּמְצָד, שׁוֹדֵד הֻשְׁדַּד וּבְרִשְׁתּוֹ נוֹצַד, מְלָשְׁנִי נִסְחַף נִצְמַת וְנִרְצָד. עָשׂוּ שְׂמָחוֹת וְלַדּוֹרוֹת קְבָעוּם, וּמִקְרָאוֹת שִׁלְּשׁוּם וְלֹא רִבְּעוּם, נִסְכְּמוּ מִמַּעַל וּלְמַטָּה טְבָעוּם, בַּסֵּפֶר נֶחֱקַק עַל מָה קְבָעוּם. רָמָה יָדְךָ לִסְלוֹחַ לַפּוֹשְׁעִים, יְהוּדִי וַהֲדַסָּה הֵקַמְתָּ מוֹשִׁיעִים, צִדְקָתָם עוֹמֶדֶת לָעַד לְשַׁעֲשׁוּעִים, חֵקֶר כְּבוֹדָם לְהִזָּכֵר לְנוֹשָׁעִים. קַנֵּא לְשִׁמְךָ נוֹרָא וְנִקְדָּשׁ, חֲזֵה כַרְמְךָ נֶהֱרַס וְנִדָּשׁ, זְרוּיֵינוּ קַבֵּץ וְשִׁיר לְךָ יְחֻדָּשׁ, קַיְּמֵם וְהַחֲיֵם בְּבִנְיַן בֵּית הַמִּקְדָּשׁ. וְכַעֲשׂוֹתְךָ נוֹרָאוֹת בְּאוֹתָן הַיָּמִים, אִתָּנוּ הַפְלֵא תְּשׁוּעַת עוֹלָמִים, מְצוֹא לְפָנֶיךָ כֹּפֶר וְתַנְחוּמִים, אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, מִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לְחַטָּאִים, וּסְלִיחָה לְפוֹשְׁעִים. עֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וָרוּחַ, לֹא כְרָעָתָם תִּגְמֹל. אֵל, הוֹרֵיתָ לָּנוּ לוֹמַר שְׁלֹשׁ עֶשְׂרֵה, וּזְכָר לָנוּ הַיּוֹם בְּרִית שְׁלשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָיו מִקֶּדֶם, כְּמוֹ שֶׁכָּתוּב: וַיֵּרֶד יהוה בֶּעָנָן, וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם, יהוה:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"הַאֲזִינָה, יהוה, תְּפִלָּתֵנוּ וְהַקְשִׁיבָה בְּקוֹל תַּחֲנוּנוֹתֵינוּ. שְׁמַע יהוה קוֹלֵנוּ נִקְרָא, וְחָנֵנוּ וַעֲנֵנוּ. שִׁמְעָה יהוה צֶדֶק, הַקְשִׁיבָה רִנָּתֵנוּ, הַאֲזִינָה תְפִלָּתֵנוּ. שְׁמַע, יהוה, וְחָנֵנוּ. יהוה, הֱיֵה עוֹזֵר לָנוּ.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"כְּרַחֵם אָב עַל בָּנִים, כֵּן תְּרַחֵם יהוה עָלֵינוּ. לַיהוה הַיְּשׁוּעָה, עַל עַמְּךָ בִרְכָתֶךָ סֶּלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶּלָה: יהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"פזמון. שליח הציבור אומר את הבית הראשון, והקהל חוזר אחריו, ולאחר מכן כל בית הקהל אומר ושליח הציבור חוזר.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"בִּמְתֵי מִסְפָּר חִלִּינוּ פָנֶיךָ, לְשַׁוְעַת נְכֵאִים אַל תַּעְלֵם אָזְנֶךָ, הַקְשֵׁב תְּחִנָּתָם מִשְּׁמֵי מְעוֹנֶךָ, כְּבִימֵי מֹר וַהֲדַס הוֹשַׁעְתָּ בָנֶיךָ.\n\nתְּהִלּוֹת יִשְׂרָאֵל אַתָּה יוֹשֵׁב, שַׁוְעָתָם מַאֲזִין וְרִנָּתָם קוֹשֵׁב, רִפְאוּת לְמַחַץ מַקְדִּים וּמְחַשֵּׁב, קְנוּיֶיךָ לְהֵיטִיב וְנָוֵיהֶם לְיַשֵּׁב.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"בִּמְתֵי מִסְפָּר חִלִּינוּ פָנֶיךָ.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"צָר וְאוֹיֵב הִלְטִישׁ עֵינָיו, פִּיהוּ פָעַר לִשְׁאֹף עָנָו, עִשֵּׁת בְּשֶׁלּוֹ לְהַשְׁמִיד קְהַל הֲמוֹנָיו, סֶגֶל לְאַבֵּד חָרַת בְּנִשְׁתְּוָנָיו.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"בִּמְתֵי מִסְפָּר חִלִּינוּ פָנֶיךָ.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"נוֹקֵם לְצָרִים וְנוֹטֵר לְאוֹיְבִים, מָדַדְתָּ מִדָּתָם כְּזָדוּ לַאֲהוּבִים, לוֹחֵם וְנִינָיו הֻתְלוּ מֻצְלָבִים, כְּבַחֲרֹזֶת דָּגִים חֹרְזוּ תְחוּבִים.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"בִּמְתֵי מִסְפָּר חִלִּינוּ פָנֶיךָ.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"יוֹם אֲשֶׁר שִׂבְּרוּ צוֹרְרִים, טִבְחָה לָשִׁית בְּעַם נְצוּרִים, חֻלְּפָה הַדָּת וְנָפְלוּ פְגָרִים, זֻלְעֲפוּ זֹעֲמוּ מוּבָסִים מֻגָּרִים.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"בִּמְתֵי מִסְפָּר חִלִּינוּ פָנֶיךָ.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"וּבְכֵן יִתְעַלֶּה שִׁמְךָ וְיִתְנַשָּׂא, הוֹדְךָ שְׁמֵי שָׁמַיִם כִּסָּה, דַּכִּים בְּרוֹמִמְךָ נְתוּנִים לִמְשִׁסָּה, גֵּיא וַאֲפָסֶיהָ תְּהִלָּתְךָ מְכַסָּה.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"בִּמְתֵי מִסְפָּר חִלִּינוּ פָנֶיךָ.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"בִּינָה הֲגִינֵנוּ עַתָּה וּרְאֵה בַצָּר, בְּאַפְּךָ קוּמָה עַל צוֹרֵר הַצָּר, אָדוֹן, קְרָאנוּךָ מִן הַמֵּצָר, אָנָּא הוֹצִיאֵנוּ לַמֶּרְחָב וְחַלְּצֵנוּ מִצָּר.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"בִּמְתֵי מִסְפָּר חִלִּינוּ פָנֶיךָ.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"מְאֹד תַּרְבֶּה לָּנוּ מְחִילָה, שְׁמַע תְּפִלָּה וְהַעֲבֵר תִּפְלָה, לוֹחֲצֵינוּ הַמְעַד וּמַלְּאֵם חַלְחָלָה, מִמֶּנּוּ רַחֲמֶיךָ לָעַד לֹא תִכְלָא.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"בִּמְתֵי מִסְפָּר חִלִּינוּ פָנֶיךָ.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, מִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לְחַטָּאִים, וּסְלִיחָה לְפוֹשְׁעִים. עֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וָרוּחַ, לֹא כְרָעָתָם תִּגְמֹל. אֵל, הוֹרֵיתָ לָּנוּ לוֹמַר שְׁלֹשׁ עֶשְׂרֵה, וּזְכָר לָנוּ הַיּוֹם בְּרִית שְׁלשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָיו מִקֶּדֶם, כְּמוֹ שֶׁכָּתוּב: וַיֵּרֶד יהוה בֶּעָנָן, וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם, יהוה:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"זְכֹר רַחֲמֶיךָ יהוה וַחֲסָדֶיךָ, כִּי מֵעוֹלָם הֵמָּה: זָכְרֵנוּ יהוה בִּרְצוֹן עַמֶּךָ, פָּקְדֵנוּ בִּישׁוּעָתֶךָ. זְכֹר עֲדָתְךָ קָנִיתָ קֶדֶם, גָּאַלְתָּ שֵׁבֶט נַחֲלָתֶךָ, הַר צִיּוֹן זֶה שָׁכַנְתָּ בּוֹ: זְכֹר יהוה חִבַּת יְרוּשָׁלָיִם, אַהֲבַת צִיּוֹן אַל תִּשְׁכַּח לָנֶצַח. אַתָּה תָקוּם תְּרַחֵם צִיּוֹן, כִּי עֵת לְחֶנְנָהּ, כִּי בָא מוֹעֵד: זְכֹר יהוה לִבְנֵי אֱדוֹם אֵת יוֹם יְרוּשָׁלָיִם, הָאוֹמְרִים עָרוּ עָרוּ, עַד הַיְסוֹד בָּהּ: זְכֹר לְאַבְרָהָם לְיִצְחָק וּלְיִשְׂרָאֵל עֲבָדֶיךָ, אֲשֶׁר נִשְׁבַּעְתָּ לָהֶם בָּךְ, וַתְּדַבֵּר אֲלֵהֶם, אַרְבֶּה אֶת זַרְעֲכֶם כְּכוֹכְבֵי הַשָּׁמַיִם, וְכָל הָאָרֶץ הַזֹּאת אֲשֶׁר אָמַרְתִּי אֶתֵּן לְזַרְעֲכֶם, וְנָחֲלוּ לְעוֹלָם: זְכֹר לַעֲבָדֶיךָ לְאַבְרָהָם לְיִצְחָק וּלְיַעֲקֹב, אַל תֵּפֶן אֶל קְשִׁי הָעָם הַזֶּה וְאֶל רִשְׁעוֹ וְאֶל חַטָּאתוֹ:\n\nאַל נָא תָשֵׁת עָלֵינוּ חַטָּאת אֲשֶׁר נוֹאַלְנוּ וַאֲשֶׁר חָטָאנוּ: חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"יש המוסיפים פיוט זה ואומרים אותו בית בית עם שליח הציבור:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"אֵל נָא, רְפָא נָא תַּחֲלוּאֵי גֶפֶן פּוֹרִיָּה, בּוֹשָׁה וַחֲפוּרָה וְאֻמְלַל פִּרְיָהּ, גְּאָלֶנָּה מִשַּׁחַת וּמִמַּכָּה טְרִיָּה, עֲנֵנוּ כְּשֶׁעָנִיתָ לְאַבְרָהָם אָבִינוּ בְּהַר הַמּוֹרִיָּה.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"דִּגְלֵי עָם פְּדוּיֵי בִּזְרוֹעַ חָשׂוּף, הַצֵּל מִנֶּגֶף וְאַל יִהְיוּ לְשִׁסּוּף, וְתַעֲנֶה קְרִיאָתֵנוּ וּלְמַעֲשֵׂה יָדֶיךָ תִּכְסֹף, עֲנֵנוּ כְּשֶׁעָנִיתָ לַאֲבוֹתֵינוּ עַל יַם סוּף.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"זְכוּת צוּר חֻצַּב הַיּוֹם לָנוּ תְגַל, חָשְׂכֵנוּ מֵאֶנֶף וּנְחֵנוּ בְּיֹשֶׁר מַעְגָּל, טַהֵר טֻמְאָתֵנוּ וְלִמְאוֹר תּוֹרָתְךָ עֵינֵינוּ גַל, עֲנֵנוּ כְּשֶׁעָנִיתָ לִיהוֹשֻׁעַ בַּגִּלְגָּל.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"יָהּ, רְאֵה דֶשֶׁן עָקוּד וְהַצְמַח לָנוּ תְרוּפָה, כַּלֵּה שׁוֹד וָשֶׁבֶר, סַעַר וְסוּפָה, לַמְּדֵנוּ וְחַכְּמֵנוּ אִמְרָתְךָ הַצְּרוּפָה, עֲנֵנוּ כְּשֶׁעָנִיתָ לִשְׁמוּאֵל בַּמִּצְפָּה.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"מֻתְמָם מֵרֶחֶם שָׁרָשָׁיו אַל תַּקְמֵל, נַקֵּנוּ מִכֶּתֶם וְשֶׁמֶץ וְלֹא נֵאָמֵל, סְעָדֵנוּ וְנִוָּשֵׁעָה וְאָרְחוֹת חֲסָדֶיךָ נִגָּמֵל, עֲנֵנוּ כְּשֶׁעָנִיתָ לְאֵלִיָּהוּ בְּהַר הַכַּרְמֶל.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"עוֹדְדֵנוּ בְּצֶדֶק מָשׁוּי מִמַּיִם וְכַפֵּר זָדוֹן וּמְשׁוּגָה, פְּדֵנוּ מִמְּהוּמַת מָוֶת וְאָחוֹר בַּל נִסּוֹגָה, צַוֵּה יְשׁוּעָתֵנוּ וּבַעֲוׂנוֹתֵינוּ אַל נִתְמוֹגְגָה, עֲנֵנוּ כְּשֶׁעָנִיתָ לְיוֹנָה בִּמְעֵי הַדָּגָה.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"קְדֻשַּׁת אִישׁ חֲסִידֶךָ זְכֹר לִיפַת פַּעֲמַיִם, רַחֲמֶיךָ תְּעוֹרֵר כִּי לָקִינוּ בְּכִפְלַיִם, שׁוּבֵנוּ תֹּקֶף לְיִרְאָתֶךָ וְלֹא נֵחָשֵׂף שׁוּלַיִם, עֲנֵנוּ כְּשֶׁעָנִיתָ לְדָוִד וְלִשְׁלֹמֹה בְנוֹ בִּירוּשָׁלַיִם.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"בתענית אסתר יש מוסיפים:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"תַּעֲנֶה לְקוֹרְאֶיךָ וְהַסְכֵּת מִמְּעוֹנִים, תִּשְׁמַע שַׁוְעַת צוֹעֲקֶיךָ, שׁוֹמֵעַ אֶל אֶבְיוֹנִים, תְּרַחֵם עַל בָּנֶיךָ כְּרַחֵם אָב עַל בָּנִים, עֲנֵנוּ כְּמוֹ שֶׁעָנִיתָ לְמָרְדְּכַי וְאֶסְתֵּר, וְתָלוּ עַל עֵץ חֲמִשִּׁים הָאָב עִם הַבָּנִים.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"מכאן כולם אומרים:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"זְכֹר לָנוּ בְּרִית אָבוֹת כַּאֲשֶׁר אָמַרְתָּ: וְזָכַרְתִּי אֶת בְּרִיתִי יַעֲקוֹב וְאַף אֶת בְּרִיתִי יִצְחָק וְאַף אֶת בְּרִיתִי אַבְרָהָם אֶזְכֹּר, וְהָאָרֶץ אֶזְכֹּר:\n\nזְכֹר לָנוּ בְּרִית רִאשׁוֹנִים כַּאֲשֶׁר אָמַרְתָּ: וְזָכַרְתִּי לָהֶם בְּרִית רִאשׁוֹנִים אֲשֶׁר הוֹצֵאתִי אוֹתָם מֵאֶרֶץ מִצְרַיִם לְעֵינֵי הַגּוֹיִם לִהְיוֹת לָהֶם לֵאלֹהִים, אֲנִי יהוה:\n\nעֲשֵׂה עִמָּנוּ כְּמָה שֶׁהִבְטַחְתָּנוּ: וְאַף גַּם זֹאת בִּהְיוֹתָם בְּאֶרֶץ אוֹיְבֵיהֶם לֹא מְאַסְתִּים וְלֹא גְעַלְתִּים לְכַלּוֹתָם לְהָפֵר בְּרִיתִי אִתָּם, כִּי אֲנִי יהוה אֱלֹהֵיהֶם: הָשֵׁב שְׁבוּתֵנוּ וְרַחֲמֵנוּ כְּמָה שֶׁכָּתוּב: וְשָׁב יהוה אֱלֹהֶיךָ אֶת שְׁבוּתְךָ וְרִחֲמֶךָ, וְשָׁב וְקִבֶּצְךָ מִכָּל הָעַמִּים אֲשֶׁר הֱפִיצְךָ יהוה אֱלֹהֶיךָ שָׁמָּה: קַבֵּץ נִדָּחֵינוּ כְּמָה שֶׁכָּתוּב: אִם יִהְיֶה נִדַּחֲךָ בִּקְצֵה הַשָּׁמָיִם, מִשָּׁם יְקַבֶּצְךָ יהוה אֱלֹהֶיךָ וּמִשָּׁם יִקָּחֶךָ: מְחֵה פְשָׁעֵינוּ כָּעָב וְכֶעָנָן כְּמָה שֶׁכָּתוּב: מָחִיתִי כָעָב פְּשָׁעֶיךָ וְכֶעָנָן חַטֹּאתֶיךָ, שׁוּבָה אֵלַי כִּי גְאַלְתִּיךָ: מְחֵה פְשָׁעֵינוּ לְמַעַנְךָ כַּאֲשֶׁר אָמַרְתָּ: אָנֹכִי אָנֹכִי הוּא מֹחֶה פְשָׁעֶיךָ לְמַעֲנִי, וְחַטֹּאתֶיךָ לֹא אֶזְכֹּר: הַלְבֵּן חֲטָאֵינוּ כַּשֶּׁלֶג וְכַצֶּמֶר כְּמָה שֶׁכָּתוּב: לְכוּ נָא וְנִוָּכְחָה יֹאמַר יהוה, אִם יִהְיוּ חֲטָאֵיכֶם כַּשָּׁנִים כַּשֶּׁלֶג יַלְבִּינוּ, אִם יַאְדִּימוּ כַתּוֹלָע כַּצֶּמֶר יִהְיוּ: זְרֹק עָלֵינוּ מַיִם טְהוֹרִים וְטַהֲרֵנוּ כְּמָה שֶׁכָּתוּב: וְזָרַקְתִּי עֲלֵיכֶם מַיִם טְהוֹרִים וּטְהַרְתֶּם, מִכֹּל טֻמְאֹתֵיכֶם וּמִכָּל גִּלּוּלֵיכֶם אֲטַהֵר אֶתְכֶם: רַחֵם עָלֵינוּ וְאַל תַּשְׁחִיתֵנוּ כְּמָה שֶׁכָּתוּב: כִּי אֵל רַחוּם יהוה אֱלֹהֶיךָ, לֹא יַרְפְּךָ וְלֹא יַשְׁחִיתֶךָ, וְלֹא יִשְׁכַּח אֶת בְּרִית אֲבֹתֶיךָ אֲשֶׁר נִשְׁבַּע לָהֶם: מוֹל אֶת לְבָבֵנוּ לְאַהֲבָה אֶת שְׁמֶךָ כְּמָה שֶׁכָּתוּב: וּמָל יהוה אֱלֹהֶיךָ אֶת לְבָבְךָ וְאֶת לְבַב זַרְעֶךָ, לְאַהֲבָה אֶת יהוה אֱלֹהֶיךָ בְּכָל לְבָבְךָ וּבְכָל נַפְשְׁךָ, לְמַעַן חַיֶּיךָ: הִמָּצֵא לָנוּ בְּבַקָּשָׁתֵנוּ כְּמָה שֶׁכָּתוּב: וּבִקַּשְׁתֶּם מִשָּׁם אֶת יהוה אֱלֹהֶיךָ וּמָצָאתָ, כִּי תִדְרְשֶׁנּוּ בְּכָל לְבָבְךָ וּבְכָל נַפְשֶׁךָ: תְּבִיאֵנוּ אֶל הַר קָדְשֶׁךָ וְשַׂמְּחֵנוּ בְּבֵית תְּפִלָּתֶךָ כְּמָה שֶׁכָּתוּב: וַהֲבִיאוֹתִים אֶל הַר קָדְשִׁי וְשִׂמַּחְתִּים בְּבֵית תְּפִלָּתִי, עוֹלוֹתֵיהֶם וְזִבְחֵיהֶם לְרָצוֹן עַל מִזְבְּחִי, כִּי בֵיתִי, בֵּית תְּפִלָּה יִקָּרֵא לְכָל הָעַמִּים:","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"פותחים את ארון הקודש ואמורים משפט משפט. יש קהילות בהם סדר המשפטים שונה וברוב הקהילות מדלגים על המשפט \"יהיו לרצון\".","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"שְׁמַע קוֹלֵנוּ, יהוה אֱלֹהֵינוּ, חוּס וְרַחֵם עָלֵינוּ, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ. הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם: אֲמָרֵינוּ הַאֲזִינָה יהוה, בִּינָה הֲגִיגֵנוּ. יִהְיוּ לְרָצוֹן אִמְרֵי פִינוּ וְהֶגְיוֹן לִבֵּנוּ לְפָנֶיךָ, יהוה צוּרֵנוּ וְגוֹאֲלֵנוּ. אַל תַּשְׁלִיכֵנוּ מִלְּפָנֶיךָ, וְרוּחַ קָדְשְׁךָ אַל תִּקַּח מִמֶּנּוּ. אַל תַּשְׁלִיכֵנוּ לְעֵת זִקְנָה, כִּכְלוֹת כֹּחֵנוּ אַל תַּעַזְבֵנוּ.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"מכאן מפסיקים לומר עם החזן בקול.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"אַל תַּעַזְבֵנוּ יהוה, אֱלֹהֵינוּ אַל תִּרְחַק מִמֶּנוּ. עֲשֵׂה עִמָּנוּ אוֹת לְטוֹבָה, וְיִרְאוּ שׂוֹנְאֵינוּ וְיֵבוֹשׁוּ, כִּי אַתָּה יהוה עֲזַרְתָּנוּ וְנִחַמְתָּנוּ. כִּי לְךָ יהוה הוֹחָלְנוּ, אַתָּה תַעֲנֶה אֲדֹנָי אֱלֹהֵינוּ.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"סוגרים את ארון הקודש.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, תָּבוֹא לְפָנֶיךָ תְּפִלָּתֵנוּ וְאַל תִּתְעַלַּם מִתְּחִנָּתֵנוּ, שֶׁאֵין אָנוּ עַזֵּי פָנִים וּקְשֵׁי עֹרֶף לוֹמַר לְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ צַדִּיקִים אֲנַחְנוּ וְלֹא חָטָאנוּ, אֲבָל אֲנַחְנוּ וַאֲבוֹתֵינוּ חָטָאנוּ.\nאָשַׁמְנוּ, בָּגַדְנוּ, גָּזַלְנוּ, דִּבַּרְנוּ דֹפִי. הֶעֱוִינוּ, וְהִרְשַׁענוּ, זַדְנוּ, חָמַסְנוּ, טָפַלְנוּ שֶׁקֶר. יָעַצְנוּ רָע, כְּזַּבְנוּ, לַצְנוּ, מָרַדְנוּ, נִאַצְנוּ, סָרַרְנוּ, עָוְינוּ, פָּשַׁעְנוּ, צָרַרְנוּ, קִשִּׁינוּ עֹרֶף. רָשַׁעְנוּ, שִׁחַתְנוּ, תִּעַבְנוּ, תָּעִינוּ, תִּעְתַּעְנוּ.\nסַרְנוּ מִמִּצְוׂתֶיךָ וּמִמִּשְׁפָּטֶיךָ הַטּוֹבִים וְלֹא שָׁוָה-לָנוּ. וְאַתָּה צַדִּיק עַל כָּל הַבָּא עָלֵינוּ, כִּי אֱמֶת עָשִׂיתָ, וַאֲנַחְנוּ הִרְשָׁעְנוּ:\n\nהִרְשַׁעְנוּ וּפָשַׁעְנוּ לָכֵן לֹא נוֹשָׁעְנוּ. וְתֵן בְּלִבֵּנוּ לַעֲזֹב דֶּרֶךְ רֶשַׁע, וְחִישׁ לָנוּ יֶשַׁע, כַּכָּתוּב עַל יַד נְבִיאֶךָ: יַעֲזוֹב רָשָׁע דַּרְכּוֹ וְאִישׁ אָוֶן מַחְשְׁבֹתָיו, וְיָשֹׁב אֶל יהוה וִירַחֲמֵהוּ, וְאֶל אֱלֹהֵינוּ כִּי יַרְבֶּה לִסְלוֹחַ:\n\nמְשִׁיחַ צִדְקֶךָ אָמַר לְפָנֶיךָ: שְׁגִיאוֹת מִי יָבִין מִנִּסְתָּרוֹת נַקֵּנִי: נַקֵּנוּ יהוה אֱלֹהֵינוּ מִכָּל פְּשָׁעֵינוּ וְטַהֲרֵנוּ מִכָּל טֻמְאוֹתֵינוּ, וּזְרֹק עָלֵינוּ מַיִם טְהוֹרִים וְטַהֲרֵנוּ, כַּכָּתוּב עַל יַד נְבִיאֶךָ: וְזָרַקְתִּי עֲלֵיכֶם מַיִם טְהוֹרִים וּטְהַרְתֶּם, מִכֹּל טֻמְאוֹתֵיכֶם וּמִכָּל גִּלּוּלֵיכֶם אֲטַהֵר אֶתְכֶם: עַמְּךָ וְנַחֲלָתְךָ רְעֵבֵי טוּבְךָ, צְמֵאֵי חַסְדְּךָ, תְּאֵבֵי יִשְׁעֶךָ. יַכִּירוּ וְיֵדְעוּ כִּי לַיהוה אֱלֹהֵינוּ הָרַחֲמִים וְהַסְּלִיחוֹת.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"אם אין אומרים תחנון מדלגים על המשך הסליחות.","cond":["shacharitTachanun","ester","shacharitTachanun"]},{"kind":"text","text":"אֵל רַחוּם שְׁמֶךָ. אֵל חַנּוּן שְׁמֶךָ. בָּנוּ נִקְרָא שְׁמֶךָ. יהוה עֲשֵׂה לְמַעַן שְׁמֶךָ. עֲשֵׂה לְמַעַן אֲמִתָּךְ. עֲשֵׂה לְמַעַן בְּרִיתָךְ. עֲשֵׂה לְמַעַן גָּדְלָךְ וְתִפְאַרְתָּךְ. עֲשֵׂה לְמַעַן דָּתָךְ. עֲשֵׂה לְמַעַן הוֹדָךְ. עֲשֵׂה לְמַעַן וִעוּדָךְ. עֲשֵׂה לְמַעַן זִכְרָךְ. עֲשֵׂה לְמַעַן חַסְדָּךְ. עֲשֵׂה לְמַעַן טוּבָךְ. עֲשֵׂה לְמַעַן יִחוּדָךְ. עֲשֵׂה לְמַעַן כְּבוֹדָךְ. עֲשֵׂה לְמַעַן לִמּוּדָךְ. עֲשֵׂה לְמַעַן מַלְכוּתָךְ. עֲשֵׂה לְמַעַן נִצְחָךְ. עֲשֵׂה לְמַעַן סוֹדָךְ. עֲשֵׂה לְמַעַן עֻזָּךְ. עֲשֵׂה לְמַעַן פְּאֵרָךְ. עֲשֵׂה לְמַעַן צִדְקָתָךְ. עֲשֵׂה לְמַעַן קְדֻשָׁתָךְ. עֲשֵׂה לְמַעַן רַחֲמֶיךָ הָרַבִּים. עֲשֵׂה לְמַעַן שְׁכִינָתָךְ. עֲשֵׂה לְמַעַן תְּהִלָּתָךְ. עֲשֵׂה לְמַעַן אוֹהֲבֶיךָ שׁוֹכְנֵי עָפָר. עֲשֵׂה לְמַעַן אַבְרָהָם יִצְחָק וְיַעֲקֹב. עֲשֵׂה לְמַעַן מֹשֶׁה וְאַהֲרֹן. עֲשֵׂה לְמַעַן דָּוִד וּשְׁלֹמֹה. עֲשֵׂה לְמַעַן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ. עֲשֵׂה לְמַעַן צִיּוֹן מִשְׁכַּן כְּבוֹדֶךָ. עֲשֵׂה לְמַעַן שִׁמְמוֹת הֵיכָלֶךָ. עֲשֵׂה לְמַעַן הֲרִיסוּת מִזְבְּחֶךָ. עֲשֵׂה לְמַעַן הֲרוּגִים עַל שֵׁם קָדְשֶׁךָ. עֲשֵׂה לְמַעַן טְבוּחִים עַל יִחוּדֶךָ. עֲשֵׂה לְמַעַן בָּאֵי בָאֵשׁ וּבַמַּיִם עַל קִדּוּשׁ שְׁמֶךָ. עֲשֵׂה לְמַעַן יוֹנְקֵי שָׁדַיִם שֶׁלֹּא חָטְאוּ. עֲשֵׂה לְמַעַן גְּמוּלֵי חָלָב שֶׁלֹּא פָשְׁעוּ. עֲשֵׂה לְמַעַן תִּינוֹקוֹת שֶׁל בֵּית רַבָּן. עֲשֵׂה לְמַעַנְךָ אִם לֹא לְמַעֲנֵנוּ. עֲשֵׂה לְמַעַנְךָ וְהוֹשִׁיעֵנוּ.\n\nעֲנֵנוּ יהוה עֲנֵנוּ. עֲנֵנוּ אֱלֹהֵינוּ עֲנֵנוּ. עֲנֵנוּ אָבִינוּ עֲנֵנוּ. עֲנֵנוּ בּוֹרְאֵנוּ עֲנֵנוּ. עֲנֵנוּ גּוֹאֲלֵנוּ עֲנֵנוּ. עֲנֵנוּ דּוֹרְשֵׁנוּ עֲנֵנוּ. עֲנֵנוּ הָאֵל הַנֶּאֱמָן עֲנֵנוּ. עֲנֵנוּ וָתִיק וְחָסִיד עֲנֵנוּ. עֲנֵנוּ זַךְ וְיָשָׁר עֲנֵנוּ. עֲנֵנוּ חַי וְקַיָּם עֲנֵנוּ. עֲנֵנוּ טוֹב וּמֵטִיב עֲנֵנוּ. עֲנֵנוּ יוֹדֵעַ יֶצֶר עֲנֵנוּ. עֲנֵנוּ כּוֹבֵשׁ כְּעָסִים עֲנֵנוּ. עֲנֵנוּ לוֹבֵשׁ צְדָקוֹת עֲנֵנוּ. עֲנֵנוּ מֶלֶךְ מַלְכֵי הַמְּלָכִים עֲנֵנוּ. עֲנֵנוּ נוֹרָא וְנִשְׂגָּב עֲנֵנוּ. עֲנֵנוּ סוֹלֵחַ וּמוֹחֵל עֲנֵנוּ. עֲנֵנוּ עוֹנֶה בְּעֵת צָרָה עֲנֵנוּ. עֲנֵנוּ פּוֹדֶה וּמַצִּיל עֲנֵנוּ. עֲנֵנוּ צַדִּיק וְיָשָׁר עֲנֵנוּ. עֲנֵנוּ קָרוֹב לְקוֹרְאָיו עֲנֵנוּ. עֲנֵנוּ רַחוּם וְחַנוּן עֲנֵנוּ. עֲנֵנוּ שׁוֹמֵעַ אֶל אֶבְיוֹנִים עֲנֵנוּ. עֲנֵנוּ תּוֹמֵךְ תְּמִימִים עֲנֵנוּ. עֲנֵנוּ אֱלֹהֵי אֲבוֹתֵינוּ עֲנֵנוּ. עֲנֵנוּ אֱלֹהֵי אַבְרָהָם עֲנֵנוּ. עֲנֵנוּ פַּחַד יִצְחָק עֲנֵנוּ. עֲנֵנוּ אֲבִיר יַעֲקֹב עֲנֵנוּ. עֲנֵנוּ עֶזְרַת הַשְּׁבָטִים עֲנֵנוּ. עֲנֵנוּ מִשְׂגַּב אִמָּהוֹת עֲנֵנוּ. עֲנֵנוּ קָשֶׁה לִכְעוֹס עֲנֵנוּ. עֲנֵנוּ רַךְ לִרְצוֹת עֲנֵנוּ. עֲנֵנוּ עוֹנֶה בְּעֵת רָצוֹן עֲנֵנוּ. עֲנֵנוּ אֲבִי יְתוֹמִים עֲנֵנוּ. עֲנֵנוּ דַּיַּן אַלְמָנוֹת עֲנֵנוּ.\n\nמִי שֶׁעָנָה לְאַבְרָהָם אָבִינוּ בְּהַר הַמּוֹרִיָּה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְיִצְחָק בְּנוֹ כְּשֶׁנֶּעֱקַד עַל גַּבֵּי הַמִּזְבֵּחַ הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְיַעֲקֹב בְּבֵית אֵל הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְיוֹסֵף בְּבֵית הָאֲסוּרִים הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לַאֲבוֹתֵינוּ עַל יַם סוּף הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְמֹשֶׁה בְּחוֹרֵב הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְאַהֲרֹן בַּמַּחְתָּה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְפִינְחָס בְּקוּמוֹ מִתּוֹךְ הָעֵדָה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לִיהוֹשֻׁעַ בַּגִּלְגָּל הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לִשְׁמוּאֵל בַּמִּצְפָּה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְדָוִד וּשְׁלֹמֹה בְנוֹ בִּירוּשָׁלָיִם הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְאֵלִיָּהוּ בְּהַר הַכַּרְמֶל הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לֶאֱלִישָׁע בִּירִיחוֹ הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְיוֹנָה בִּמְעֵי הַדָּגָה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְחִזְקִיָּהוּ מֶלֶךְ יְהוּדָה בְּחָלְיוֹ הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לַחֲנַנְיָה מִישָׁאֵל וַעֲזַרְיָה בְּתוֹךְ כִּבְשַׁן הָאֵשׁ הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְדָנִיֵּאל בְּגוֹב הָאֲרָיוֹת הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְמָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְעֶזְרָא בַּגּוֹלָה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְכָל הַצַּדִּיקִים וְהַחֲסִידִים וְהַתְּמִימִים וְהַיְּשָׁרִים הוּא יַעֲנֵנוּ.\n\nרַחֲמָנָא דְעָנֵי לַעֲנִיֵי עֲנֵינָא. רַחֲמָנָא דְעָנֵי לִתְבִירֵי לִבָּא עֲנֵינָן. רַחֲמָנָא דְעָנֵי לְמַכִּיכֵי רוּחָא עֲנֵינָן. רַחֲמָנָא עֲנֵינָן. רַחֲמָנָא חוּס. רַחֲמָנָא פְּרוֹק. רַחֲמָנָא שְׁזִיב. רַחֲמָנָא רְחַם עֲלָן. הַשְׁתָּא בַּעֲגָלָא וּבִזְמַן קָרִיב.","cond":["shacharitTachanun","ester","shacharitTachanun"]},{"kind":"header","text":"אבינו מלכנו","cond":["shacharitTachanun","noGedalya"]},{"kind":"instruction","text":"אבינו מלכנו","cond":["shacharitTachanun","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חָטָאנוּ לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, אֵין לָנוּ מֶלֶךְ אֶלָּא אָתָּה.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה עִמָּנוּ לְמַעַן שְׁמֶךָ.","cond":["shacharitTachanun","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חַדֵּשׁ עָלֵינוּ שָׁנָה טוֹבָה.","cond":["shacharitTachanun","noGedalya","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, בָּרֵךְ עָלֵינוּ שָׁנָה טוֹבָה.","cond":["shacharitTachanun","noGedalya","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, בַּטֵּל מֵעָלֵינוּ כָּל גְּזֵרוֹת קָשׁוֹת.\nאָבִינוּ מַלְכֵּנוּ, בַּטֵּל מַחְשְׁבוֹת שׂוֹנְאֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, הָפֵר עֲצַת אוֹיְבֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה כָּל צַר וּמַשְׂטִין מֵעָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, סְתֹם פִּיּוֹת מַשְׂטִינֵינוּ וּמְקַטְרְגֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה דֶבֶר וְחֶרֶב וְרָעָב וּשְׁבִי וּמַשְׁחִית וְעָוׂן וּשְׁמַד מִבְּנֵי בְרִיתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, מְנַע מַגֵּפָה מִנַּחֲלָתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, סְלַח וּמְחַל לְכָל עֲוׂנוֹתֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, מְחֵה וְהַעֲבֵר פְּשָׁעֵינוּ וְחַטֹּאתֵינוּ מִנֶּגֶד עֵינֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, מְחֹק בְּרַחֲמֶיךָ הָרַבִּים כָּל שִׁטְרֵי חוֹבוֹתֵינוּ.","cond":["shacharitTachanun","noGedalya"]},{"kind":"instruction","text":"מכאן אומרים בקול עם החזן","cond":["shacharitTachanun","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, הַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, שְׁלַח רְפוּאָה שְׁלֵמָה לְחוֹלֵי עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, קְרַע רֹע גְּזַר דִּינֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ בְּזִכְרוֹן טוֹב לְפָנֶיךָ.","cond":["shacharitTachanun","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר חַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר גְּאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר פַּרְנָסָה וְכַלְכָּלָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר זְכֻיּוֹת.\nאָבִינוּ מַלְכֵּנוּ, כָָּתְבֵנוּ בְּסֵפֶר סְלִיחָה וּמְחִילָה.","cond":["shacharitTachanun","noGedalya","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לְחַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִגְאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לְפַרְנָסָה וְכַלְכָּלָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִזְכֻיּוֹת.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִסְלִיחָה וּמְחִילָה.","cond":["shacharitTachanun","noGedalya","noGedalya"]},{"kind":"instruction","text":"עד כאן עם החזן","cond":["shacharitTachanun","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, הַצְמַח לָנוּ יְשׁוּעָה בְּקָרוֹב.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן יִשְׂרָאֵל עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן מְשִׁיחֶךָ.\nאָבִינוּ מַלְכֵּנוּ, מַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, מַלֵּא אֲסָמֵינוּ שָׂבָע.\nאָבִינוּ מַלְכֵּנוּ, שְׁמַע קוֹלֵנוּ, חוּס וְרַחֵם עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, קַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, פְּתַח שַׁעֲרֵי שָׁמַיִם לִתְפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, זְכֹר כִּי עָפָר אֲנַחְנוּ.\nאָבִינוּ מַלְכֵּנוּ, נָא אַל תְּשִׁיבֵנוּ רֵיקָם מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, תְּהֵא הַשָּׁעָה הַזֹּאת שְׁעַת רַחֲמִים וְעֵת רָצוֹן מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, חֲמֹל עָלֵינוּ וְעַל עוֹלָלֵינוּ וְטַפֵּנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן הֲרוּגִים עַל שֶׁם קָדְשֶׁךָ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן טְבוּחִים עַל יִחוּדֶךָ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן בָּאֵי בָאֵשׁ וּבַמָּיִּם עַל קִדּוּשׁ שְׁמֶךָ.\nאָבִינוּ מַלְכֵּנוּ, נְקֹם לְעֵינֵינוּ נִקְמַת דַּם עֲבָדֶיךָ הַשָּׁפוּךְ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַנְךָ אִם לֹא לְמַעַנֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַנְךָ וְהוֹשִׁיעֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַן רַחֲמֶיךָ הָרַבִּים.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַן שִׁמְךָ הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא שֶׁנִּקְרָא עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, חָנֵּנוּ וַעֲנֵנוּ כִּי אֵין בָּנוּ מַעֲשִׂים, עֲשֵׂה עִמָּנוּ צְדָקָה וָחֶסֶד וְהוֹשִׁיעֵנוּ.","cond":["shacharitTachanun","noGedalya"]},{"kind":"header","text":"אבינו מלכנו","cond":["shacharitTachanun","ayt"]},{"kind":"instruction","text":"אבינו מלכנו","cond":["shacharitTachanun","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חָטָאנוּ לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, אֵין לָנוּ מֶלֶךְ אֶלָּא אָתָּה.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה עִמָּנוּ לְמַעַן שְׁמֶךָ.","cond":["shacharitTachanun","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חַדֵּשׁ עָלֵינוּ שָׁנָה טוֹבָה.","cond":["shacharitTachanun","ayt","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, בָּרֵךְ עָלֵינוּ שָׁנָה טוֹבָה.","cond":["shacharitTachanun","ayt","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, בַּטֵּל מֵעָלֵינוּ כָּל גְּזֵרוֹת קָשׁוֹת.\nאָבִינוּ מַלְכֵּנוּ, בַּטֵּל מַחְשְׁבוֹת שׂוֹנְאֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, הָפֵר עֲצַת אוֹיְבֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה כָּל צַר וּמַשְׂטִין מֵעָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, סְתֹם פִּיּוֹת מַשְׂטִינֵינוּ וּמְקַטְרְגֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה דֶבֶר וְחֶרֶב וְרָעָב וּשְׁבִי וּמַשְׁחִית וְעָוׂן וּשְׁמַד מִבְּנֵי בְרִיתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, מְנַע מַגֵּפָה מִנַּחֲלָתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, סְלַח וּמְחַל לְכָל עֲוׂנוֹתֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, מְחֵה וְהַעֲבֵר פְּשָׁעֵינוּ וְחַטֹּאתֵינוּ מִנֶּגֶד עֵינֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, מְחֹק בְּרַחֲמֶיךָ הָרַבִּים כָּל שִׁטְרֵי חוֹבוֹתֵינוּ.","cond":["shacharitTachanun","ayt"]},{"kind":"instruction","text":"מכאן אומרים בקול עם החזן","cond":["shacharitTachanun","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, הַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, שְׁלַח רְפוּאָה שְׁלֵמָה לְחוֹלֵי עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, קְרַע רֹע גְּזַר דִּינֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ בְּזִכְרוֹן טוֹב לְפָנֶיךָ.","cond":["shacharitTachanun","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר חַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר גְּאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר פַּרְנָסָה וְכַלְכָּלָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר זְכֻיּוֹת.\nאָבִינוּ מַלְכֵּנוּ, כָָּתְבֵנוּ בְּסֵפֶר סְלִיחָה וּמְחִילָה.","cond":["shacharitTachanun","ayt","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לְחַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִגְאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לְפַרְנָסָה וְכַלְכָּלָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִזְכֻיּוֹת.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִסְלִיחָה וּמְחִילָה.","cond":["shacharitTachanun","ayt","noGedalya"]},{"kind":"instruction","text":"עד כאן עם החזן","cond":["shacharitTachanun","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, הַצְמַח לָנוּ יְשׁוּעָה בְּקָרוֹב.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן יִשְׂרָאֵל עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן מְשִׁיחֶךָ.\nאָבִינוּ מַלְכֵּנוּ, מַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, מַלֵּא אֲסָמֵינוּ שָׂבָע.\nאָבִינוּ מַלְכֵּנוּ, שְׁמַע קוֹלֵנוּ, חוּס וְרַחֵם עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, קַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, פְּתַח שַׁעֲרֵי שָׁמַיִם לִתְפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, זְכֹר כִּי עָפָר אֲנַחְנוּ.\nאָבִינוּ מַלְכֵּנוּ, נָא אַל תְּשִׁיבֵנוּ רֵיקָם מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, תְּהֵא הַשָּׁעָה הַזֹּאת שְׁעַת רַחֲמִים וְעֵת רָצוֹן מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, חֲמֹל עָלֵינוּ וְעַל עוֹלָלֵינוּ וְטַפֵּנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן הֲרוּגִים עַל שֶׁם קָדְשֶׁךָ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן טְבוּחִים עַל יִחוּדֶךָ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן בָּאֵי בָאֵשׁ וּבַמָּיִּם עַל קִדּוּשׁ שְׁמֶךָ.\nאָבִינוּ מַלְכֵּנוּ, נְקֹם לְעֵינֵינוּ נִקְמַת דַּם עֲבָדֶיךָ הַשָּׁפוּךְ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַנְךָ אִם לֹא לְמַעַנֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַנְךָ וְהוֹשִׁיעֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַן רַחֲמֶיךָ הָרַבִּים.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַן שִׁמְךָ הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא שֶׁנִּקְרָא עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, חָנֵּנוּ וַעֲנֵנוּ כִּי אֵין בָּנוּ מַעֲשִׂים, עֲשֵׂה עִמָּנוּ צְדָקָה וָחֶסֶד וְהוֹשִׁיעֵנוּ.","cond":["shacharitTachanun","ayt"]},{"kind":"header","text":"תחנון","cond":["shacharitTachanun"]},{"kind":"instruction","text":"יש נוהגים שלא לומר תחנון היום, ובפרט בארץ ישראל שיכולים בקלות להגיע לירושלים לשמוח עימם בשמחת פורים דמוקפין.","cond":["shacharitTachanun","purim_meshulash_tachanun_message"]},{"kind":"instruction","text":"בבית האבל אין אומרים תחנון ומדלגים לחצי קדיש.","cond":["shacharitTachanun"]},{"kind":"instruction","text":"נפילת אפיים","cond":["shacharitTachanun","noMonThu"]},{"kind":"text","text":"וַיֹּאמֶר דָּוִד אֶל גָּד, צַר לִי מְאֹד, נִפְּלָה נָּא בְיַד יהוה כִּי רַבִּים רַחֲמָיו, וּבְיַד אָדָם אַל אֶפֹּלָה:\n\nרַחוּם וְחַנּוּן חָטָאתִי לְפָנֶיך. יהוה מָלֵא רַחֲמִים, רַחֵם עָלַי וְקַבֵּל תַּחֲנוּנָי.\n\nיהוה, אַל בְּאַפְּךָ תוֹכִיחֵנִי וְאַל בַּחֲמָתְךָ תְיַסְּרֵנִי: חָנֵּנִי יהוה כִּי אֻמְלַל אָנִי, רְפָאֵנִי יהוה כִּי נִבְהֲלוּ עֲצָמָי: וְנַפְשִׁי נִבְהֲלָה מְאֹד, וְאַתָּה יהוה עַד מָתָי: שׁוּבָה יהוה חַלְּצָה נַפְשִׁי, הוֹשִׁיעֵנִי לְמַעַן חַסְדֶּךָ: כִּי אֵין בַּמָּוֶת זִכְרֶךָ, בִּשְׁאוֹל מִי יוֹדֶה לָּךְ: יָגַעְתִּי בְאַנְחָתִי, אַשְׂחֶה בְכָל לַיְלָה מִטָּתִי, בְּדִמְעָתִי עַרְשִׂי אַמְסֶה: עָשְׁשָׁה מִכַּעַס עֵינִי, עָתְקָה בְּכָל צוֹרְרָי: סוּרוּ מִמֶּנִּי כָּל פֹּעֲלֵי אָוֶן כִּי שָׁמַע יהוה קוֹל בִּכְיִי: שָׁמַע יהוה תְּחִנָּתִי, יהוה תְּפִלָּתִי יִקָּח: יֵבֹשׁוּ וְיִבָּהֲלוּ מְאֹד כָּל אֹיְבָי, יָשֻׁבוּ יֵבֹשׁוּ רָגַע:","cond":["shacharitTachanun","noMonThu"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, תָּבוֹא לְפָנֶיךָ תְּפִלָּתֵנוּ וְאַל תִּתְעַלַּם מִתְּחִנָּתֵנוּ, שֶׁאֵין אֲנַחְנוּ עַזֵּי פָנִים וּקְשֵׁי עֹרֶף לוֹמַר לְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ צַדִּיקִים אֲנַחְנוּ וְלֹא חָטָאנוּ, אֲבָל אֲנַחְנוּ וַאֲבוֹתֵינוּ חָטָאנוּ.\nאָשַׁמְנוּ, בָּגַדְנוּ, גָּזַלְנוּ, דִּבַּרְנוּ דֹפִי. הֶעֱוִינוּ, וְהִרְשַׁעְנוּ, זַדְנוּ, חָמַסְנוּ, טָפַלְנוּ שֶׁקֶר. יָעַצְנוּ רָע, כִּזַּבְנוּ, לַצְנוּ, מָרַדְנוּ, נִאַצְנוּ, סָרַרְנוּ, עָוִינוּ, פָּשַׁעְנוּ, צָרַרְנוּ, קִשִּׁינוּ עֹרֶף. רָשַׁעְנוּ, שִׁחַתְנוּ, תִּעַבְנוּ, תָּעִינוּ, תִּעְתַּעְנוּ.\nסַרְנוּ מִמִּצְוׂתֶיךָ וּמִמִּשְׁפָּטֶיךָ הַטּוֹבִים וְלֹא שָׁוָה-לָנוּ. וְאַתָּה צַדִּיק עַל כָּל הַבָּא עָלֵינוּ, כִּי אֱמֶת עָשִׂיתָ, וַאֲנַחְנוּ הִרְשָׁעְנוּ:","cond":["shacharitTachanun","monThu","noSlichot"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","monThu","noSlichot"]},{"kind":"text","text":"אֵל אֶרֶךְ אַפַּיִם אַתָּה וּבַעַל הָרַחֲמִים נִקְרֵאתָ, וְדֶרֶךְ תְּשׁוּבָה הוֹרֵיתָ, גְּדֻלַּת רַחֲמֶיךָ וַחֲסָדֶיךָ תִּזְכֹּר הַיּוֹם וּבְכָל יוֹם לְזֶרַע יְדִידֶיךָ. תֵּפֶן אֵלֵינוּ בְּרַחֲמִים, כִּי אַתָּה הוּא בַּעַל הָרַחֲמִים. בְּתַחֲנוּן וּבִתְפִלָּה פָּנֶיךָ נְקַדֵּם, כְּהוֹדַעתָּ לֶעָנָו מִקֶּדֶם. מֵחֲרוֹן אַפְּךָ שׁוּב, כְּמוֹ בְּתוֹרָתְךָ כָּתוּב. וּבְצֵל כְּנָפֶיךָ נֶחְסֶה וְנִתְלוֹנָן, כְּיוֹם וַיֵּרֶד יהוה בֶּעָנָן. תַּעֲבֹר עַל פֶּשַׁע וְתִמְחֶה אָשָׁם, כְּיוֹם וַיִּתְיַצֵּב עִמּוֹ שָׁם. תַּאֲזִין שַׁוְעָתֵנוּ וְתַקְשִׁיב מֶנּוּ מַאֲמָר, כְּיוֹם וַיִּקְרָא בְשֵׁם יהוה, וְשָׁם נֶאֱמַר:","cond":["shacharitTachanun","monThu","noSlichot"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","monThu","noSlichot"]},{"kind":"instruction","text":"תחנונים לשני וחמישי","cond":["shacharitTachanun","monThu"]},{"kind":"text","text":"וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית, וְהִרְבָּה לְהָשִׁיב אַפּוֹ וְלֹא יָעִיר כָּל חֲמָתוֹ: אַתָּה יהוה, לֹא תִכְלָא רַחֲמֶיךָ מִמֶּנּוּ, חַסְדְּךָ וַאֲמִתְּךָ תָּמִיד יִצְּרוּנוּ. הוֹשִׁיעֵנוּ יהוה אֱלֹהֵינוּ וְקַבְּצֵנוּ מִן הַגּוֹיִם, לְהֹדוֹת לְשֵׁם קָדְשֶׁךָ, לְהִשְׁתַּבֵּחַ בִּתְהִלָּתֶךָ: אִם עֲוׂנוֹת תִּשְמָר יָהּ, אֲדֹנָי, מִי יַעֲמֹד: כִּי עִמְּךָ הַסְּלִיחָה, לְמַעַן תִּוָּרֵא: לֹא כַחֲטָאֵינוּ תַּעֲשֶׂה לָנוּ וְלֹא כַעֲוׂנֹתֵינוּ תִּגְמֹל עָלֵינוּ. אִם עֲוׂנֵינוּ עָנוּ בָנוּ, יהוה, עֲשֵׂה לְמַעַן שְׁמֶךָ. זְכֹר רַחֲמֶיךָ יהוה וַחֲסָדֶיךָ, כִּי מֵעוֹלָם הֵמָּה: יַעֲנֵנוּ יהוה בְּיוֹם צָרָה, יְשַׂגְּבֵנוּ שֵׁם אֱלֹהֵי יַעֲקֹב. יהוה הושִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ: אָבִינוּ מַלְכֵּנוּ, חָנֵּנוּ וַעֲנֵנוּ, כִּי אֵין בָּנוּ מַעֲשִׂים. צְדָקָה עֲשֵׂה עִמָּנוּ לְמַעַן שְׁמֶךָ. אֲדוֹנֵינוּ אֱלֹהֵינוּ, שְׁמַע קוֹל תַּחֲנוּנֵינוּ, וּזְכָר לָנוּ אֶת בְּרִית אֲבוֹתֵינוּ, וְהוֹשִׁיעֵנוּ לְמַעַן שְׁמֶךָ.\n\nוְעַתָּה אֲדֹנָי אֱלֹהֵינוּ אֲשֶׁר הוֹצֵאתָ אֶת עַמְּךָ מֵאֶרֶץ מִצְרַיִם בְּיָד חֲזָקָה, וַתַּעַשׂ לְךָ שֵׁם כַּיּוֹם הַזֶּה, חָטָאנוּ רָשָׁעְנוּ: אֲדֹנָי, כְּכָל צִדְקֹתֶךָ יָשָׁב נָא אַפְּךָ וַחֲמָתְךָ מֵעִירְךָ יְרוּשָׁלַיִם הַר קָדְשֶׁךָ, כִּי בַחֲטָאֵינוּ וּבַעֲוׂנוֹת אֲבֹתֵינוּ, יְרוּשָׁלִַם וְעַמְּךָ לְחֶרְפָּה לְכָל סְבִיבֹתֵינוּ: וְעַתָּה שְׁמַע אֱלֹהֵינוּ אֶל תְּפִלַּת עַבְדְּךָ וְאֶל תַּחֲנוּנָיו, וְהָאֵר פָּנֶיךָ עַל מִקְדָּשְׁךָ הַשָּׁמֵם, לְמַעַן אֲדֹנָי: הַטֵּה אֱלֹהַי אָזְנְךָ וּשְׁמָע, פְּקַח עֵינֶיךָ וּרְאֵה שֹׁמְמֹתֵינוּ וְהָעִיר אֲשֶׁר נִקְרָא שִׁמְךָ עָלֶיהָ, כִּי לֹא עַל צִדְקֹתֵינוּ אֲנַחְנוּ מַפִּילִים תַּחֲנוּנֵינוּ לְפָנֶיךָ, כִּי עַל רַחֲמֶיךָ הָרַבִּים: אֲדֹנָי שְׁמָעָה, אֲדֹנָי סְלָחָה, אֲדֹנָי הַקֲשִׁיבָה וַעֲשֵׂה אַל תְּאַחַר, לְמַעֲנְךָ אֱלֹהַי, כִּי שִׁמְךָ נִקְרָא עַל עִירְךָ וְעַל עַמֶּךָ:\n\nאָבִינוּ הָאָב הָרַחֲמָן, הַרְאֵנוּ אוֹת לְטוֹבָה וְקַבֵּץ נְפוּצוֹתֵינוּ מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ. יַכִּירוּ וְיֵדְעוּ כָּל הַגּוֹיִם, כִּי אַתָּה יהוה אֱלֹהֵינוּ. וְעַתָּה יהוה אָבִינוּ אָתָּה, אֲנַחְנוּ הַחֹמֶר וְאַתָּה יֹצְרֵנוּ וּמַעֲשֵׂה יָדְךָ כֻּלָּנוּ: הוֹשִׁיעֵנוּ לְמַעַן שְׁמֶךָ, צוּרֵנוּ מַלְכֵּנוּ וְגוֹאֲלֵנוּ. חוּסָה יהוה עַל עַמֶּךָ וְאַל תִּתֵּן נַחֲלָתְךָ לְחֶרְפָּה לִמְשָׁל בָּם גּוֹיִם, לָמָּה יֹאמְרוּ בָעַמִּים אַיֵּה אֱלֹהֵיהֶם: יָדַעְנוּ כִּי חָטָאנוּ וְאֵין מִי יַעֲמֹד בַּעֲדֵנוּ. שִׁמְךָ הַגָּדוֹל יַעֲמָד לָנוּ בְּעֵת צָרָה. יָדַעְנוּ כִּי אֵין בָּנוּ מַעֲשִׂים. צְדָקָה עֲשֵׂה עִמָּנוּ לְמַעַן שְׁמֶךָ. כְּרַחֵם אָב עַל בָּנִים כֵּן תְּרַחֵם יהוה עָלֵינוּ, וְהוֹשִׁיעֵנוּ לְמַעַן שְׁמֶךָ. חֲמֹל עַל עַמֶּךָ, רַחֵם עַל נַחֲלָתֶךָ, חוּסָה נָּא כְּרֹב רַחֲמֶיךָ, חָנֵנוּ וַעֲנֵנוּ. כִּי לְךָ יהוה הַצְּדָקָה, עֹשֵׂה נִפְלָאוֹת בְּכָל עֵת.\n\nהַבֵּט נָא רַחֵם נָא עַל עַמְּךָ מְהֵרָה לְמַעַן שְׁמֶךָ. בְּרַחֲמֶיךָ הָרַבִּים יהוה אֱלֹהֵינוּ חוּס וְרַחֵם וְהוֹשִׁיעָה צֹאן מַרְעִיתֶךָ, וְאַל יִמְשָׁל בָּנוּ קֶצֶף, כִּי לְךָ עֵינֵינוּ תְלוּיוֹת. הוֹשִׁיֵענוּ לְמַעַן שְׁמֶךָ, רַחֵם עָלֵינוּ לְמַעַן בְּרִיתֶךָ, הַבִּיטָה וַעֲנֵנוּ בְּעֵת צָרָה, כִּי לְךָ יהוה הַיְשׁוּעָה, בְּךָ תוֹחַלְתֵּנוּ אֱלוֹהַּ סְלִיחוֹת. אָנָּא סְלַח נָא, אֵל טוֹב וְסַלָּח, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.\n\nאָנָּא מֶלֶךְ חַנּוּן וְרַחוּם, זְכֹר וְהַבֵּט לִבְרִית בֵּין הַבְּתָרִים וְתֵרָאֶה לְפָנֶיךָ עֲקֵדַת יָחִיד לְמַעַן יִשרָאֵל. אָבִינוּ מַלְכֵּנוּ חָנֵּנוּ וַעֲנֵנוּ, כִּי שִׁמְךָ הַגָּדוֹל נִקְרָא עָלֵינוּ. עֹשֵׂה נִפְלָאות בְּכָל עֵת, עֲשֵׂה עִמָּנוּ כְּחַסְדֶּךָ. חַנּוּן וְרַחוּם, הַבִּיטָה וַעֲנֵנוּ בְּעֵת צָרָה, כִּי לְךָ יהוה הַיְשׁוּעָה. אָבִינוּ מַלְכֵּנוּ מַחֲסֵנוּ, אַל תַּעַשׁ עִמָּנוּ כְּרֹעַ מַעֲלָלֵנוּ, זְכוֹר רַחֲמֶיךָ יהוה וַחֲסָדֶיךָ, וּכְרֹב טוּבְךָ הושִׁיעֵנוּ וַחֲמָל נָא עָלֵינוּ, כִּי אֵין לָנוּ אֱלוֹהַּ אַחֵר מִבַּלְעָדֶיךָ צוּרֵנוּ. אַל תַּעַזְבֵנוּ יהוה אֱלֹהֵינוּ, אַל תִּרְחַק מִמֶּנוּ, כִּי נַפְשֵׁנוּ קְצָרָה. מֵחֶרֵב וּמִשְּׁבִי וּמִדֶּבֶר וּמִמַּגֵּפָה וּמִכָּל צָרָה וְיָגוֹן הַצִּילֵנוּ כִּי לְךָ קִוִּינוּ, וְאַל תַּכְלִימֵנוּ יהוה אֱלֹהֵינוּ וְהָאֵר פָּנֶיךָ בָּנוּ וּזְכֹר לָנוּ אֶת בְּרִית אֲבוֹתֵינוּ וְהוֹשִׁיעֵנוּ לְמַעַן שְׁמֶךָ. רְאֵה בְצָרוֹתֵינוּ וּשְׁמַע קוֹל תְּפִלָּתֵנוּ, כִּי אַתָּה שׁוֹמֵע תְּפִלַּת כָּל פֶּה.\n\nאֵל רַחוּם וְחַנּוּן, רַחֵם עָלֵינוּ וְעַל כָּל מַעֲשיךָ, כִּי אֵין כָּמוךָ יהוה אֱלֹהֵינוּ, אָנָּא שָׂא נָא פְשָׁעֵינוּ. אָבִינוּ מַלְכֵּנוּ צוּרֵנוּ וְגוֹאֲלֵנוּ, אֵל חַי וְקַיָּם הֶחָסִין בַּכֹּחַ, חָסִיד וְטוֹב עַל כָּל מַעֲשֶׂיךָ, כִּי אַתָּה הוּא יהוה אֱלֹהֵינוּ. אֵל אֶרֶךְ אַפַּיִם וּמָלֵא רַחֲמִים, עֲשֵׂה עִמָּנוּ כְּרֹב רַחֲמֶיךָ, וְהוֹשִׁיעֵנוּ לְמַעַן שְׁמֶךָ. שְׁמַע מַלְכֵּנוּ תְּפִלָּתֵנוּ, וּמִיַּד אוֹיְבֵינוּ הַצִּילֵנוּ. שְׁמַע מַלְכֵּנוּ תְּפִלָתֵנוּ וּמִכָּל צָרָה וְיָגון הַצִּילֵנוּ. אָבִינוּ מַלְכֵּנוּ אַתָּה, וְשִׁמְךָ עָלֵינוּ נִקְרָא, אַל תַּנִּיחֵנוּ. אַל תַּעַזְבֵנוּ אָבִינוּ, וְאַל תִּטְּשֵׁנוּ בּוֹרְאֵנוּ, וְאַל תִּשְׁכָּחֵנוּ יוֹצְרֵנוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.\n\nאֵין כָּמוֹך חַנּוּן וְרַחוּם יהוה אֱלֹהֵינוּ, אֵין כָּמוֹךָ אֵל אֶרֶך אַפַּיִם וְרַב חֶסֶד וֶאֱמֶת. הוֹשִׁיעֵנוּ בְּרַחֲמֶיךָ הָרַבִּים, מֵרַעַשׁ וּמֵרֹגֶז הַצִּילֵנוּ. זְכֹר לַעֲבָדֶיך לְאַבְרָהָם לְיִצְחָק וּלְיַעֲקֹב, אַל תֵּפֶן אֶל קָשְיֵנוּ וְאֶל רִשְׁעֵנוּ וְאֶל חַטָּאתֵנוּ. שׁוּב מֵחָרוֹן אַפֶּךָ, וְהִנָּחֵם עַל הָרָעָה לְעַמֶּךָ: וְהָסֵר מִמֶּנּוּ מַכַּת הַמָּוֶת כִּי רַחוּם אָתָּה, כִּי כֵן דַּרְכֶּךָ, עוֹשֶׂה חֶסֶד חִנָּם בְּכָל דוֹר וָדוֹר. חוּסָה יהוה עַל עַמֶּךָ וְהַצִּילֵנוּ מִזַּעֲמֶךָ, וְהָסֵר מִמֶּנּוּ מַכַּת הַמַּגֵּפָה וּגְזֵרָה קָשָׁה, כִּי אַתָּה שׁוֹמֵר יִשְׂרָאֵל. לְךָ אֲדֹנָי הַצְּדָקָה וְלָנוּ בֹּשֶׁת הַפָּנִים. מַה נִּתְאוֹנֵן, מַה נֹּאמַר, מַה נְּדַבֵּר וּמַה נִּצְטַדַּק. נְחַפְּשָׂה דְרָכֵינוּ וְנַחְקֹרָה וְנָשׁוּבָה אֵלֶיךָ, כִּי יְמִינְךָ פְשׁוּטָה לְקַבֵּל שָׁבִים. אָנָּא יהוה הוֹשִׁיעָה נָּא, אָנָּא יהוה הַצְלִיחָה נָּא: אָנָּא יהוה עֲנֵנוּ בְיוֹם קָרְאֵנוּ. לְךָ יהוה חִכִּינוּ, לְךָ יהוה קִוִּינוּ, לְךָ יהוה נְיַחֵל. אַל תֶּחֱשֶׁה וּתְעַנֵּנוּ, כִּי נַאֲמוּ גוֹיִם: אָבְדָה תִקְוָתָם. כָּל בֶּרֶך וְכָל קוֹמָה לְךָ לְבַד תִּשְׁתַּחֲוֶה.\n\nהַפּוֹתֵחַ יָד בִּתְשׁוּבַה לְקַבֵּל פּוֹשְׁעִים וְחַטָּאִים, נִבְהֲלָה נַפְשֵׁנוּ מֵרֹב עִצְּבוֹנֵנוּ. אַל תִּשְׁכָּחֵנוּ נֶצַח, קוּמָה וְהוֹשִׁיעֵנוּ כִּי חָסִינוּ בָך. אָבִינוּ מַלְכֵּנוּ, אִם אֵין בָּנוּ צְדָקָה וּמַעֲשִׂים טוֹבִים, זְכָר לָנוּ אֶת בְּרִית אֲבוֹתֵינוּ וְעֵדוֹתֵנוּ בּכָל יוֹם: \"יהוה אֶחָד\". הַבִּיטָה בְעָנְיֵנוּ, כִּי רַבּוּ מַכְאוֹבֵינוּ וְצָרוֹת לְבָבֵנוּ. חוּסָה יהוה עָלֵינוּ, וְאַל תִּשְׁפֹּך חֲרוֹנְךָ עָלֵינוּ, כִּי אֲנַחְנוּ עַמְּךָ בְּנֵי בְרִיתֶךָ. אֵל, הַבִּיטָה, דַּל כְּבוֹדֵנוּ בַּגּוֹיִם וְשִׁקְּצוּנוּ כְּטֻמְאַת הַנִּדָּה. עַד מָתַי עֻזְּךָ בַּשְּׁבִי, וְתִפְאַרְתְּךָ בְּיַד צָר. עוֹרְרָה גְבוּרָתֶךָ וְקִנְאָתְךָ עַל אוֹיְבֶיךָ, הֵם יֵבוֹשׁוּ וְיֵחַתּוּ מִגְּבוּרָתָם. וְאַל יִמְעֲטוּ לְפָנֶיךָ תְּלָאוֹתֵינוּ, מַהֵר יְקַדְּמוּנוּ רַחֲמֶיךָ בְּיוֹם צָרָתֵנוּ. וְאִם לֹא לְמַעֲנֵנוּ, לְמַעַנְךָ פְעַל, וְאַל תַּשְׁחִית זֵכֶר שְׁאֵרִיתֵנוּ, וְחֹן אֹם הַמְיַחֲדִים שִׁמְךָ פַּעֲמַיִם בְּכָל יוֹם תָּמִיד בְּאַהֲבָה וְאוֹמְרִים: \"שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:\"","cond":["shacharitTachanun","monThu"]},{"kind":"instruction","text":"נפילת אפיים","cond":["shacharitTachanun","monThu"]},{"kind":"text","text":"וַיֹּאמֶר דָּוִד אֶל גָּד, צַר לִי מְאֹד, נִפְּלָה נָּא בְיַד יהוה כִּי רַבִּים רַחֲמָיו, וּבְיַד אָדָם אַל אֶפֹּלָה:\n\nרַחוּם וְחַנּוּן חָטָאתִי לְפָנֶיך. יהוה מָלֵא רַחֲמִים, רַחֵם עָלַי וְקַבֵּל תַּחֲנוּנָי.\n\nיהוה, אַל בְּאַפְּךָ תוֹכִיחֵנִי וְאַל בַּחֲמָתְךָ תְיַסְּרֵנִי: חָנֵּנִי יהוה כִּי אֻמְלַל אָנִי, רְפָאֵנִי יהוה כִּי נִבְהֲלוּ עֲצָמָי: וְנַפְשִׁי נִבְהֲלָה מְאֹד, וְאַתָּה יהוה עַד מָתָי: שׁוּבָה יהוה חַלְּצָה נַפְשִׁי, הוֹשִׁיעֵנִי לְמַעַן חַסְדֶּךָ: כִּי אֵין בַּמָּוֶת זִכְרֶךָ, בִּשְׁאוֹל מִי יוֹדֶה לָּךְ: יָגַעְתִּי בְאַנְחָתִי, אַשְׂחֶה בְכָל לַיְלָה מִטָּתִי, בְּדִמְעָתִי עַרְשִׂי אַמְסֶה: עָשְׁשָׁה מִכַּעַס עֵינִי, עָתְקָה בְּכָל צוֹרְרָי: סוּרוּ מִמֶּנִּי כָּל פֹּעֲלֵי אָוֶן כִּי שָׁמַע יהוה קוֹל בִּכְיִי: שָׁמַע יהוה תְּחִנָּתִי, יהוה תְּפִלָּתִי יִקָּח: יֵבֹשׁוּ וְיִבָּהֲלוּ מְאֹד כָּל אֹיְבָי, יָשֻׁבוּ יֵבֹשׁוּ רָגַע:","cond":["shacharitTachanun","monThu"]},{"kind":"text","text":"יהוה אֱלֹהֵי יִשְׂרָאֵל, שׁוּב מֵחֲרוֹן אַפֶּךָ וְהִנָּחֵם עַל הָרָעָה לְעַמֶּךָ:\nהַבֵּט מִשָּׁמַיִם וּרְאֵה כִּי הָיִינוּ לַעַג וָקֶלֶס בַגּוֹיִם, נֶחְשַׁבְנוּ כַּצֹּאן לַטֶּבַח יוּבָל, לַהֲרֹג וּלְאַבֵּד וּלְמַכָּה וּלְחֶרְפָּה.\nוּבְכָל זֹאת שִׁמְךָ לֹא שָׁכָחְנוּ, נָא אַל תִּשְׁכָּחֵנוּ.\nיהוה אֱלֹהֵי יִשְׂרָאֵל, שׁוּב מֵחֲרוֹן אַפֶּךָ וְהִנָּחֵם עַל הָרָעָה לְעַמֶּךָ:\n\nזָרִים אוֹמְרֵים אֵין תּוֹחֶלֶת וְתִקְוָה, חֹן אֹם לְשִׁמְךָ מְקַוֶּה, טָהוֹר, יְשׁוּעָתֵנוּ קָרְבָה, יָגַעְנוּ וְלֹא הוּנַח לָנוּ, רַחֲמֶיךָ יִכְבְּשׁוּ אֶת כַּעַסְךָ מֵעָלֵינוּ.\nאָנָּא שׁוּב מֵחֲרוֹנְךָ וְרַחֵם סְגֻלָּה אֲשֶׁר בָּחַרְתָּ.\nיהוה אֱלֹהֵי יִשְׂרָאֵל, שׁוּב מֵחֲרוֹן אַפֶּךָ וְהִנָּחֵם עַל הָרָעָה לְעַמֶּךָ:\n\nחוּסָה יהוה עָלֵינוּ בְּרַחֲמֶיךָ וְאַל תִּתְּנֵנוּ בִּידֵי אַכְזָרִים. לָמָּה יֹאמְרוּ הַגּוֹיִם \"אַיֵּה נָא אֱלֹהֵיהֶם\"? לְמַעַנְךָ עֲשֵׂה עִמָּנוּ חֶסֶד וְאַל תְּאַחַר.\nאָנָּא שׁוּב מֵחֲרוֹנְךָ וְרַחֵם סְגֻלָּה אֲשֶׁר בָּחַרְתָּ.\nיהוה אֱלֹהֵי יִשְׂרָאֵל, שׁוּב מֵחֲרוֹן אַפֶּךָ וְהִנָּחֵם עַל הָרָעָה לְעַמֶּךָ:\n\nקוֹלֵנוּ תִשְׁמַע וְתָחֹן, וְאַל תִּטְּשֵׁנוּ בְּיַד אֹיְבֵינוּ לִמְחוֹת אֶת שְׁמֵנוּ. זְכֹר אֲשֶׁר נִשְׁבַּעְתָּ לַאֲבוֹתֵינוּ \"כְּכוֹכְבֵי הַשָּׁמַיִם אַרְבֶּה אֶת זַרְעֲכֶם\", וְעַתָּה נִשְׁאַרְנוּ מְעַט מֵהַרְבֵּה.\nוּבְכָל זֹאת שִׁמְךָ לֹא שָׁכָחְנוּ, נָא אַל תִּשְׁכָּחֵנוּ.\nיהוה אֱלֹהֵי יִשְׂרָאֵל, שׁוּב מֵחֲרוֹן אַפֶּךָ וְהִנָּחֵם עַל הָרָעָה לְעַמֶּךָ:\n\nעָזְרֵנוּ אֱלֹהֵי יִשְׁעֵנוּ עַל דְּבַר כְּבוֹד שְׁמֶךָ, וְהַצִּילֵנוּ וְכַפֵּר עַל חַטֹּאתֵינוּ לְמַעַן שְׁמֶךָ:\nיהוה אֱלֹהֵי יִשְׂרָאֵל, שׁוּב מֵחֲרוֹן אַפֶּךָ וְהִנָּחֵם עַל הָרָעָה לְעַמֶּךָ:","cond":["shacharitTachanun","monThu"]},{"kind":"instruction","text":"שומר ישראל","cond":["shacharitTachanun"]},{"kind":"text","text":"שׁוֹמֵר יִשְׂרָאֵל, שְׁמֹר שְׁאֵרִית יִשְׂרָאֵל, וְאַל יֹאבַד יִשְׂרָאֵל, הָאוֹמְרִים שְׁמַע יִשְׂרָאֵל.\nשׁוֹמֵר גּוֹי אֶחָד, שְׁמֹר שְׁאֵרִית עַם אֶחָד, וְאַל יֹאבַד גּוֹי אֶחָד, הַמְיַחֲדִים שִׁמְךָ יהוה אֱלֹהֵינוּ יהוה אֶחָד.\nשׁוֹמֵר גּוֹי קָדוֹשׁ, שְׁמֹר שְׁאֵרִית עַם קָדוֹשׁ, וְאַל יֹאבַד גּוֹי קָדוֹשׁ, הַמְשַׁלְּשִׁים בְּשָׁלֹשׁ קְדֻשּׁוֹת לְקָדוֹשׁ.\n\nמִתְרַצֶּה בְּרַחֲמִים וּמִתְפַּיֵּס בְּתַחֲנוּנִים, הִתְרַצֶּה וְהִתְפַּיֵּס לְדוֹר עָנִי. כִּי אֵין עוֹזֵר.\nאָבִינוּ מַלְכֵּנוּ. חָנֵּנוּ וַעֲנֵנוּ, כִּי אֵין בָּנוּ מַעֲשִׂים, עֲשֵׂה עִמָּנוּ צְדָקָה וָחֶסֶד וְהוֹשִׁיעֵנוּ.\n\nוַאֲנַחְנוּ לֹא נֵדַע מַה נַּעֲשֶׂה, כִּי עָלֶיךָ עֵינֵינוּ: זְכֹר רַחֲמֶיךָ יהוה וַחֲסָדֶיךָ, כִּי מֵעוֹלָם הֵמָּה: יְהִי חַסְדְּךָ יהוה עָלֵינוּ, כַּאֲשֶׁר יִחַלְנוּ לָךְ: אַל תִּזְכָּר לָנוּ עֲוׂנוֹת רִאשׁוֹנִים, מַהֵר יְקַדְּמוּנוּ רַחֲמֶיךָ, כִּי דַלּוֹנוּ מְאֹד: חָנֵּנוּ יהוה חָנֵּנוּ, כִּי רַב שָׂבַעְנוּ בוּז: בְּרֹגֶז רַחֵם תִּזְכּוֹר: כִּי הוּא יָדַע יִצְרֵנוּ, זָכוּר כִּי עָפָר אֲנָחְנוּ: עָזְרֵנוּ אֱלֹהֵי יִשְׁעֵנוּ עַל דְּבַר כְּבוֹד שְׁמֶךָ, וְהַצִּילֵנוּ וְכַפֵּר עַל חַטֹּאתֵינוּ לְמַעַן שְׁמֶךָ:","cond":["shacharitTachanun"]},{"kind":"instruction","text":"חצי קדיש","cond":["noMusaf"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":["noMusaf"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noMusaf","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noMusaf","ayt"]},{"kind":"header","text":"הוצאת ספר תורה","cond":["tora"]},{"kind":"instruction","text":"הוצאת ספר תורה","cond":["tora"]},{"kind":"instruction","text":"נוסח אשכנז:","cond":["tora","lErechApayim"]},{"kind":"text","text":"אֵל אֶרֶךְ אַפַּיִם וְרַב חֶסֶד וֶאֱמֶת, אַל בְּאַפְּךָ תוֹכִיחֵנוּ. חוּסָה יהוה עַל עַמֶּךָ וְהוֹשִׁיעֵנוּ מִכָּל רָע. חָטָאנוּ לְךָ אָדוֹן, סְלַח נָא כְּרֹב רַחֲמֶיךָ אֵל.","cond":["tora","lErechApayim"]},{"kind":"instruction","text":"נוסח פולין:","cond":["tora","lErechApayim"]},{"kind":"text","text":"אֵל אֶרֶךְ אַפַּיִם וּמָלֵא רַחֲמִים, אַל תַּסְתֵּר פָּנֶיךָ מִמֶּנּוּ. חוּסָה יהוה עַל שְׁאֵרִית יִשְׂרָאֵל עַמֶּךָ וְהַצִּילֵנוּ מִכָּל רָע. חָטָאנוּ לְךָ אָדוֹן, סְלַח נָא כְּרֹב רַחֲמֶיךָ אֵל.","cond":["tora","lErechApayim"]},{"kind":"text","text":"וַיְהִי בִּנְסֹעַ הָאָרֹן וַיֹּאמֶר מֹשֶׁה קוּמָה יהוה וְיָפֻצוּ אֹיְבֶיךָ וְיָנֻסוּ מְשַׂנְאֶיךָ מִפָּנֶיךָ: כִּי מִצִּיּוֹן תֵּצֵא תוֹרָה וּדְבַר יהוה מִירוּשָׁלָיִם: בָּרוּךְ שֶׁנָּתַן תּוֹרָה לְעַמּוֹ יִשְׂרָאֵל בִּקְדֻשָּׁתוֹ.\n\nבְּרִיךְ שְׁמֵהּ דְּמָרֵא עָלְמָא. בְּרִיךְ כִּתְרָךְ וְאַתְרָךְ. יְהֵא רְעוּתָךְ עִם עַמָּךְ יִשְׂרָאֵל לְעָלַם. וּפֻרְקַן יְמִינָךְ אַחֲזֵי לְעַמָּךְ בְּבֵית מַקְדְּשָׁךְ. וּלְאַמְטוֹיֵי לָנָא מִטּוּב נְהוֹרָךְ וּלְקַבֵּל צְלוֹתָנָא בְּרַחֲמִין. יְהֵא רַעֲוָא קֳדָמָךְ דְּתוֹרִיךְ לָן חַיִּין בְּטִיבוּ. וְלֶהֱוֵי אֲנָא פְקִידָא בְּגוֹ צַדִּיקַיָּא. לְמִרְחַם עָלַי וּלְמִנְטַר יָתִי וְיַת כָּל דִּי לִי וְדִי לְעַמָּךְ יִשְׂרָאֵל. אַנְתְּ הוּא זָן לְכֹלָּא וּמְפַרְנֵס לְכֹלָּא. אַנְתְּ הוּא שַׁלִּיט עַל כֹּלָּא. אַנְתְּ הוּא דְשַׁלִּיט עַל מַלְכַיָּא. וּמַלְכוּתָא דִּילָךְ הִיא. אֲנָא עַבְדָּא דְקֻדְשָׁא בְּרִיךְ הוּא דְּסָגִידְנָא קַמֵּהּ וּמִקַּמֵּי דִּיקַר אוֹרַיְתֵהּ בְּכָל עִדָּן וְעִדָּן. לָא עַל אֱנָשׁ רָחִיצְנָא וְלָא עַל בַּר אֱלָהִין סָמִיכְנָא. אֶלָּא בֶּאֱלָהָא דִשְׁמַיָּא. דְּהוּא אֱלָהָא קְשׁוֹט וְאוֹרַיְתֵהּ קְשׁוֹט וּנְבִיאוֹהִי קְשׁוֹט. וּמַסְגֵּא לְמֶעְבַּד טַבְוָן וּקְשׁוֹט. בֵּהּ אֲנָא רָחִיץ. וְלִשְׁמֵהּ יַקִּירָא קַדִּישָׁא אֲנָא אֵמַר תֻּשְׁבְּחָן. יְהֵא רַעֲוָא קֳדָמָךְ דְּתִפְתַּח לִבָּאִי בְּאוֹרַיְתָא. וְתַשְׁלִים מִשְׁאֲלִין דְּלִבָּאי וְלִבָּא דְכָל עַמָּךְ יִשְׂרָאֵל. לְטַב וּלְחַיִּין וְלִשְׁלָם.\n\nחזן - גַּדְּלוּ לַיהוה אִתִּי וּנְרוֹמְמָה שְׁמוֹ יַחְדָּו:\nקהל - לְךָ יהוה הַגְּדֻלָּה וְהַגְּבוּרָה וְהַתִּפְאֶרֶת וְהַנֵּצַח וְהַהוֹד כִּי כֹל בַּשָּׁמַיִם וּבָאָרֶץ: לְךָ יהוה הַמַּמְלָכָה וְהַמִּתְנַשֵּׂא לְכֹל לְרֹאשׁ: רוֹמְמוּ יהוה אֱלֹהֵינוּ וְהִשְׁתַּחֲווּ לַהֲדֹם רַגְלָיו קָדוֹשׁ הוּא: רוֹמְמוּ יהוה אֱלֹהֵינוּ וְהִשְׁתַּחֲווּ לְהַר קָדְשׁוֹ כִּי קָדוֹשׁ יהוה אֱלֹהֵינוּ:\n\nאַב הָרַחֲמִים, הוּא יְרַחֵם עַם עֲמוּסִים, וְיִזְכּוֹר בְּרִית אֵיתָנִים, וְיַצִּיל נַפְשׁוֹתֵינוּ מִן הַשָּׁעוֹת הָרָעוֹת, וְיִגְעַר בְּיֵצֶר הָרָע מִן הַנְּשוּאִים, וְיָחֹן אוֹתָנוּ לִפְלֵיטַת עוֹלָמִים, וִימַלֵּא מִשְׁאֲלוֹתֵינוּ בְּמִדָּה טוֹבָה, יְשׁוּעָה וְרַחֲמִים.","cond":["tora"]},{"kind":"header","text":"קריאת התורה","cond":["tora"]},{"kind":"instruction","text":"קריאת התורה","cond":["tora"]},{"kind":"instruction","text":"לפני הקריאה מברך העולה:","cond":["tora"]},{"kind":"instruction","text":"חזן:","cond":["tora"]},{"kind":"text","text":"בָּרְכוּ אֶת יהוה הַמְבֹרָךְ.","cond":["tora"]},{"kind":"instruction","text":"קהל וחזן:","cond":["tora"]},{"kind":"text","text":"בָּרוּךְ יהוה הַמְבֹרָךְ לְעוֹלָם וָעֶד.","cond":["tora"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר בָּחַר בָּנוּ מִכָּל הָעַמִּים וְנָתַן לָנוּ אֶת תּוֹרָתוֹ. בָּרוּךְ אַתָּה יהוה, נוֹתֵן הַתּוֹרָה.","cond":["tora"]},{"kind":"instruction","text":"לאחר הקריאה מברך העולה:","cond":["tora"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר נָתַן לָנוּ תּוֹרַת אֱמֶת וְחַיֵּי עוֹלָם נָטַע בְּתוֹכֵנוּ. בָּרוּךְ אַתָּה יהוה, נוֹתֵן הַתּוֹרָה.\n\n=====","cond":["tora"]},{"kind":"header","text":"ברכת הגומל","cond":["tora"]},{"kind":"instruction","text":"ברכת הגומל","cond":["tora"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַגּוֹמֵל לְחַיָּבִים טוֹבוֹת, שֶגְּמָלַנִי כָּל טוֹב.\n\nקהל - אָמֵן. מִי שֶגְּמָלְךָ טוֹב, הוּא יִגְמָלְךָ כָּל טוֹב, סֶלָה.","cond":["tora"]},{"kind":"instruction","text":"חצי קדיש","cond":["tora"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":["tora"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["tora","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["tora","ayt"]},{"kind":"instruction","text":"הגבהה וגלילה","cond":["tora"]},{"kind":"text","text":"וְזֹאת הַתּוֹרָה אֲשֶׁר שָׂם מֹשֶׁה לִפְנֵי בְּנֵי יִשְׂרָאֵל: עַל פִּי יהוה בְּיַד מֹשֶׁה:","cond":["tora"]},{"kind":"text","text":"יְהִי רָצוֹן מִלִּפְנֵי אָבִינוּ שֶׁבַּשָּׁמַיִם לְכוֹנֵן אֶת בֵּית חַיֵּינוּ, וּלְהָשִׁיב אֶת שְׁכִינָתוֹ בְּתוֹכֵנוּ בִּמְהֵרָה בְיָמֵינוּ, וְנֹאמַר אָמֵן.\n\nיְהִי רָצוֹן מִלִּפְנֵי אָבִינוּ שֶׁבַּשָּׁמַיִם לְרַחֵם עָלֵינוּ וְעַל פְּלֵיטָתֵינוּ, וְלִמְנוֹעַ מַשְׁחִית וּמַגֵּפָה מֵעָלֵינוּ וּמֵעַל כָּל עַמּוֹ בֵּית יִשְׂרָאֵל, וְנֹאמַר אָמֵן.\n\nיְהִי רָצוֹן מִלִּפְנֵי אָבִינוּ שֶׁבַּשָּׁמַיִם לְקַיֵּם בָּנוּ חַכְמֵי יִשְׂרָאֵל, הֵם וּנְשֵׁיהֶם וּבְנֵיהֶם וּבְנוֹתֵיהֶם, וְתַלְמִידֵיהֶם וְתַלְמִידֵי תַלְמִידֵיהֶם, בְּכָל מְקוֹמוֹת מוֹשְׁבוֹתֵיהֶם, וְנֹאמַר אָמֵן.\n\nיְהִי רָצוֹן מִלִּפְנֵי אָבִינוּ שֶׁבַּשָּׁמַיִם שֶׁנִּשְׁמַע וְנִתְבַּשֵׂר בְּשׂוֹרוֹת טוֹבוֹת, יְשׁוּעוֹת וְנֶחָמוֹת, וִיקַבֵּץ נִדָּחֵינוּ מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ. וְנֹאמַר אָמֵן.\n\nאַחֵינוּ כָּל בֵּית יִשְׂרָאֵל, הַנְּתוּנִים בְּצָרָה וּבְשִׁבְיָה, הָעוֹמְדִים בֵּין בַּיָּם וּבֵין בַּיַּבָּשָׁה, הַמָּקוֹם יְרַחֵם עֲלֵיהֶם וְיוֹצִיאֵם מִצָּרָה לִרְוָחָה, וּמֵאֲפֵלָה לְאוֹרָה, וּמִשִּׁעְבּוּד לִגְאֻלָּה, הַשְׁתָּא בַּעֲגָלָא וּבִזְמַן קָרִיב, וְנֹאמַר אָמֵן.","cond":["tora","monThuTachanun"]},{"kind":"header","text":"הפטרה","cond":["tishaaBeav"]},{"kind":"instruction","text":"הפטרה","cond":["tishaaBeav"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר בָּחַר בִּנְבִיאִים טוֹבִים וְרָצָה בְדִבְרֵיהֶם הַנֶּאֱמָרִים בֶּאֱמֶת. בָּרוּךְ אַתָּה יהוה, הַבּוֹחֵר בַּתּוֹרָה וּבְמֹשֶׁה עַבְדּוֹ וּבְיִשְׂרָאֵל עַמּוֹ וּבִנְבִיאֵי הָאֱמֶת וָצֶדֶק.\n\nאָסֹף אֲסִיפֵם נְאֻם יהוה אֵין עֲנָבִים בַּגֶּפֶן וְאֵין תְּאֵנִים בַּתְּאֵנָה וְהֶעָלֶה נָבֵל וָאֶתֵּן לָהֶם יַעַבְרוּם: עַל מָה אֲנַחְנוּ יֹשְׁבִים הֵאָסְפוּ וְנָבוֹא אֶל עָרֵי הַמִּבְצָר וְנִדְּמָה שָּׁם כִּי יהוה אֱלֹהֵינוּ הֲדִמָּנוּ וַיַּשְׁקֵנוּ מֵי רֹאשׁ כִּי חָטָאנוּ לַיהוה: קַוֵּה לְשָׁלוֹם וְאֵין טוֹב לְעֵת מַרְפֵּה וְהִנֵּה בְעָתָה: מִדָּן נִשְׁמַע נַחְרַת סוּסָיו מִקּוֹל מִצְהֲלוֹת אַבִּירָיו רָעֲשָׁה כָּל הָאָרֶץ וַיָּבוֹאוּ וַיֹּאכְלוּ אֶרֶץ וּמְלוֹאָהּ עִיר וְיֹשְׁבֵי בָהּ: כִּי הִנְנִי מְשַׁלֵּחַ בָּכֶם נְחָשִׁים צִפְעֹנִים אֲשֶׁר אֵין לָהֶם לָחַשׁ וְנִשְּׁכוּ אֶתְכֶם נְאֻם יהוה: מַבְלִיגִיתִי עֲלֵי יָגוֹן עָלַי לִבִּי דַוָּי: הִנֵּה קוֹל שַׁוְעַת בַּת עַמִּי מֵאֶרֶץ מַרְחַקִּים הַיהוה אֵין בְּצִיּוֹן אִם מַלְכָּהּ אֵין בָּהּ מַדּוּעַ הִכְעִסוּנִי בִּפְסִלֵיהֶם בְּהַבְלֵי נֵכָר: עָבַר קָצִיר כָּלָה קָיִץ וַאֲנַחְנוּ לוֹא נוֹשָׁעְנוּ: עַל שֶׁבֶר בַּת עַמִּי הָשְׁבָּרְתִּי קָדַרְתִּי שַׁמָּה הֶחֱזִקָתְנִי: הַצֳרִי אֵין בְּגִלְעָד אִם רֹפֵא אֵין שָׁם כִּי מַדּוּעַ לֹא עָלְתָה אֲרֻכַת בַּת עַמִּי: מִי יִתֵּן רֹאשִׁי מַיִם וְעֵינִי מְקוֹר דִּמְעָה וְאֶבְכֶּה יוֹמָם וָלַיְלָה אֵת חַלְלֵי בַת עַמִּי: מִי יִתְּנֵנִי בַמִּדְבָּר מְלוֹן אֹרְחִים וְאֶעֶזְבָה אֶת עַמִּי וְאֵלְכָה מֵאִתָּם כִּי כֻלָּם מְנָאֲפִים עֲצֶרֶת בֹּגְדִים: וַיַּדְרְכוּ אֶת לְשׁוֹנָם קַשְׁתָּם שֶׁקֶר וְלֹא לֶאֱמוּנָה גָּבְרוּ בָאָרֶץ כִּי מֵרָעָה אֶל רָעָה יָצָאוּ וְאֹתִי לֹא יָדָעוּ נְאֻם יהוה: אִישׁ מֵרֵעֵהוּ הִשָּׁמֵרוּ וְעַל כָּל אָח אַל תִּבְטָחוּ כִּי כָל אָח עָקוֹב יַעְקֹב וְכָל רֵעַ רָכִיל יַהֲלֹךְ: וְאִישׁ בְּרֵעֵהוּ יְהָתֵלּוּ וֶאֱמֶת לֹא יְדַבֵּרוּ לִמְּדוּ לְשׁוֹנָם דַּבֶּר שֶׁקֶר הַעֲוֵה נִלְאוּ: שִׁבְתְּךָ בְּתוֹךְ מִרְמָה בְּמִרְמָה מֵאֲנוּ דַעַת אוֹתִי נְאֻם יהוה: לָכֵן כֹּה אָמַר יהוה צְבָאוֹת הִנְנִי צוֹרְפָם וּבְחַנְתִּים כִּי אֵיךְ אֶעֱשֶׂה מִפְּנֵי בַּת עַמִּי: חֵץ שָׁחוּט לְשׁוֹנָם מִרְמָה דִבֵּר בְּפִיו שָׁלוֹם אֶת רֵעֵהוּ יְדַבֵּר וּבְקִרְבּוֹ יָשִׂים אָרְבּוֹ: הַעַל אֵלֶּה לֹא אֶפְקָד בָּם נְאֻם יהוה אִם בְּגוֹי אֲשֶׁר כָּזֶה לֹא תִתְנַקֵּם נַפְשִׁי: עַל הֶהָרִים אֶשָּׂא בְכִי וָנֶהִי וְעַל נְאוֹת מִדְבָּר קִינָה כִּי נִצְּתוּ מִבְּלִי אִישׁ עֹבֵר וְלֹא שָׁמְעוּ קוֹל מִקְנֶה מֵעוֹף הַשָּׁמַיִם וְעַד בְּהֵמָה נָדְדוּ הָלָכוּ: וְנָתַתִּי אֶת יְרוּשָׁלַיִם לְגַלִּים מְעוֹן תַּנִּים וְאֶת עָרֵי יְהוּדָה אֶתֵּן שְׁמָמָה מִבְּלִי יוֹשֵׁב: מִי הָאִישׁ הֶחָכָם וְיָבֵן אֶת זֹאת וַאֲשֶׁר דִּבֶּר פִּי יהוה אֵלָיו וְיַגִּדָהּ עַל מָה אָבְדָה הָאָרֶץ נִצְּתָה כַמִּדְבָּר מִבְּלִי עֹבֵר: וַיֹּאמֶר יהוה עַל עָזְבָם אֶת תּוֹרָתִי אֲשֶׁר נָתַתִּי לִפְנֵיהֶם וְלֹא שָׁמְעוּ בְקוֹלִי וְלֹא הָלְכוּ בָהּ: וַיֵּלְכוּ אַחֲרֵי שְׁרִרוּת לִבָּם וְאַחֲרֵי הַבְּעָלִים אֲשֶׁר לִמְּדוּם אֲבוֹתָם: לָכֵן כֹּה אָמַר יהוה צְבָאוֹת אֱלֹהֵי יִשְׂרָאֵל הִנְנִי מַאֲכִילָם אֶת הָעָם הַזֶּה לַעֲנָה וְהִשְׁקִיתִים מֵי רֹאשׁ: וַהֲפִצוֹתִים בַּגּוֹיִם אֲשֶׁר לֹא יָדְעוּ הֵמָּה וַאֲבוֹתָם וְשִׁלַּחְתִּי אַחֲרֵיהֶם אֶת הַחֶרֶב עַד כַּלּוֹתִי אוֹתָם: כֹּה אָמַר יהוה צְבָאוֹת הִתְבּוֹנְנוּ וְקִרְאוּ לַמְקוֹנְנוֹת וּתְבוֹאֶינָה וְאֶל הַחֲכָמוֹת שִׁלְחוּ וְתָבוֹאנָה: וּתְמַהֵרְנָה וְתִשֶּׂנָה עָלֵינוּ נֶהִי וְתֵרַדְנָה עֵינֵינוּ דִּמְעָה וְעַפְעַפֵּינוּ יִזְּלוּ מָיִם: כִּי קוֹל נְהִי נִשְׁמַע מִצִּיּוֹן אֵיךְ שֻׁדָּדְנוּ בֹּשְׁנוּ מְאֹד כִּי עָזַבְנוּ אָרֶץ כִּי הִשְׁלִיכוּ מִשְׁכְּנוֹתֵינוּ: כִּי שְׁמַעְנָה נָשִׁים דְּבַר יהוה וְתִקַּח אָזְנְכֶם דְּבַר פִּיו וְלַמֵּדְנָה בְנוֹתֵיכֶם נֶהִי וְאִשָּׁה רְעוּתָהּ קִינָה: כִּי עָלָה מָוֶת בְּחַלּוֹנֵינוּ בָּא בְּאַרְמְנוֹתֵינוּ לְהַכְרִית עוֹלָל מִחוּץ בַּחוּרִים מֵרְחֹבוֹת: דַּבֵּר כֹּה נְאֻם יהוה וְנָפְלָה נִבְלַת הָאָדָם כְּדֹמֶן עַל פְּנֵי הַשָּׂדֶה וּכְעָמִיר מֵאַחֲרֵי הַקֹּצֵר וְאֵין מְאַסֵּף: כֹּה אָמַר יהוה אַל יִתְהַלֵּל חָכָם בְּחָכְמָתוֹ וְאַל יִתְהַלֵּל הַגִּבּוֹר בִּגְבוּרָתוֹ אַל יִתְהַלֵּל עָשִׁיר בְּעָשְׁרוֹ: כִּי אִם בְּזֹאת יִתְהַלֵּל הַמִּתְהַלֵּל הַשְׂכֵּל וְיָדֹעַ אוֹתִי כִּי אֲנִי יהוה עֹשֶׂה חֶסֶד מִשְׁפָּט וּצְדָקָה בָּאָרֶץ כִּי בְאֵלֶּה חָפַצְתִּי נְאֻם יהוה:\n\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעולָם, צוּר כָּל הָעוֹלָמִים, צַדִּיק בְּכָל הַדּוֹרוֹת, הָאֵל הַנֶּאֱמָן הָאוֹמֵר וְעוֹשֶׂה, הַמְדַבֵּר וּמְקַיֵּם שֶׁכָּל דְּבָרָיו אֱמֶת וָצֶדֶק. נֶאֱמָן אַתָּה הוּא יהוה אֱלֹהֵינוּ וְנֶאֱמָנִים דְּבָרֶיךָ, וְדָבָר אֶחָד מִדְּבָרֶיךָ אָחוֹר לֹא יָשׁוּב רֵיקָם, כִּי אֵל מֶלֶךְ נֶאֱמָן וְרַחֲמָן אָתָּה. בָּרוּךְ אַתָּה יהוה, הָאֵל הַנֶּאֱמָן בְּכָל דְּבָרָיו.\n\nרַחֵם עַל צִיּוֹן כִּי הִיא בֵּית חַיֵּינוּ, וְלַעֲלוּבַת נֶפֶשׁ תּוֹשִׁיעַ בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יהוה, מְשַׂמֵּחַ צִיּוֹן בְּבָנֶיהָ.\n\nשַׂמְּחֵנוּ יהוה אֱלֹהֵינוּ בְּאֵלִיָּהוּ הַנָּבִיא עַבְדֶּךָ וּבְמַלְכוּת בֵּית דָּוִד מְשִׁיחֶךָ, בִּמְהֵרָה יָבוֹא וְיָגֵל לִבֵּנוּ, עַל כִּסְאוֹ לֹא יֵשֵׁב זָר וְלֹא יִנְחֲלוּ עוֹד אֲחֵרִים אֶת כְּבוֹדוֹ, כִּי בְשֵׁם קָדְשְׁךָ נִשְׁבַּעְתָּ לוֹ שֶׁלֹּא יִכְבֶּה נֵרוֹ לְעוֹלָם וָעֶד. בָּרוּךְ אַתָּה יהוה, מָגֵן דָּוִד.","cond":["tishaaBeav"]},{"kind":"header","text":"הכנסת ספר תורה","cond":["tora"]},{"kind":"instruction","text":"הכנסת ספר תורה","cond":["tora"]},{"kind":"text","text":"יְהַלְלוּ אֶת שֵׁם יהוה, כִּי נִשְׂגָּב שְׁמוֹ לְבַדּוֹ.\nוהקהל אומרים - הוֹדוֹ עַל אֶרֶץ וְשָׁמָיִם: וַיָּרֶם קֶרֶן לְעַמּוֹ, תְּהִלָּה לְכָל חֲסִידָיו, לִבְנֵי יִשְׂרָאֵל עַם קְרוֹבוֹ, הַלְלוּיָהּ:\n\nלְדָוִד מִזְמוֹר, לַיהוה הָאָרֶץ וּמְלוֹאָהּ, תֵּבֵל וְיֹשְׁבֵי בָהּ: כִּי הוּא עַל יַמִּים יְסָדָהּ, וְעַל נְהָרוֹת יְכוֹנְנֶהָ: מִי יַעֲלֶה בְהַר יהוה, וּמִי יָקוּם בִּמְקוֹם קָדְשׁוֹ: נְקִי כַפַּיִם וּבַר לֵבָב, אֲשֶׁר לֹא נָשָׂא לַשָּׁוְא נַפְשִׁי וְלֹא נִשְׁבַּע לְמִרְמָה: יִשָּׂא בְרָכָה מֵאֵת יהוה, וּצְדָקָה מֵאֱלֹהֵי יִשְׁעוֹ: זֶה דּוֹר דֹּרְשָׁיו, מְבַקְשֵׁי פָנֶיךָ יַעֲקֹב סֶלָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וְהִנָּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבוֹא מֶלֶךְ הַכָּבוֹד: מִי זֶה מֶלֶךְ הַכָּבוֹד, יהוה עִזּוּז וְגִבּוֹר, יהוה גִּבּוֹר מִלְחָמָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבֹא מֶלֶךְ הַכָּבוֹד: מִי הוּא זֶה מֶלֶךְ הַכָּבוֹד, יהוה צְבָאוֹת הוּא מֶלֶךְ הַכָּבוֹד סֶלָה:","cond":["tora"]},{"kind":"instruction","text":"כשמכניסים את הספר אומרים","cond":["tora"]},{"kind":"text","text":"וּבְנֻחֹה יֹאמַר: שׁוּבָה יהוה רִבְבוֹת אַלְפֵי יִשְׂרָאֵל: קוּמָה יהוה לִמְנוּחָתֶךָ, אַתָּה וַאֲרוֹן עֻזֶּךָ: כֹּהֲנֶיךָ יִלְבְּשׁוּ צֶדֶק, וַחֲסִידֶיךָ יְרַנֵּנוּ: בַּעֲבוּר דָּוִד עַבְדֶּךָ אַל תָּשֵׁב פְּנֵי מְשִׁיחֶךָ: כִּי לֶקַח טוֹב נָתַתִּי לָכֶם, תּוֹרָתִי אַל תַּעֲזֹבוּ: עֵץ חַיִּים הִיא לַמַּחֲזִיקִים בָּהּ, וְתֹמְכֶיהָ מְאֻשָּׁר: דְּרָכֶיהָ דַרְכֵי נֹעַם וְכָל נְתִיבוֹתֶיהָ שָׁלוֹם: הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם:","cond":["tora"]},{"kind":"header","text":"מגילת אסתר","cond":["megilatEster"]},{"kind":"instruction","text":"הקורא את המגילה מברך לפניה שלוש ברכות גם בלילה וגם ביום. לדעת השו\"ע מברכים שהחיינו רק בלילה (ואם לא קרא בלילה יברך ביום). בברכת שהחיינו ביום יכוון גם על שאר מצוות היום: מתנות לאביונים, משלוח מנות ומשתה ושמחה. הנוהגים כדעת השו\"ע יכוונו על זה בלילה.","cond":["megilatEster"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ עַל מִקְרָא מְגִלָּה.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁעָשָׂה נִסִּים לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁהֶחֱיָנוּ וְקִיְּמָנוּ וְהִגִּיעָנוּ לַזְּמַן הַזֶּה.","cond":["megilatEster"]},{"kind":"header","text":"פרק א'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק א'","cond":["megilatEster"]},{"kind":"text","text":"וַיְהִי בִּימֵי אֲחַשְׁוֵרוֹשׁ, הוּא אֲחַשְׁוֵרוֹשׁ הַמֹּלֵךְ מֵהֹדּוּ וְעַד כּוּשׁ, שֶׁבַע וְעֶשְׂרִים וּמֵאָה מְדִינָה: בַּיָּמִים הָהֵם, כְּשֶׁבֶת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ עַל כִּסֵּא מַלְכוּתוֹ אֲשֶׁר בְּשׁוּשַׁן הַבִּירָה: בִּשְׁנַת שָׁלוֹשׁ לְמָלְכוֹ עָשָׂה מִשְׁתֶּה לְכָל שָׂרָיו וַעֲבָדָיו, חֵיל פָּרַס וּמָדַי הַפַּרְתְּמִים וְשָׂרֵי הַמְּדִינוֹת לְפָנָיו: בְּהַרְאֹתוֹ אֶת עֹשֶׁר כְּבוֹד מַלְכוּתוֹ וְאֶת יְקָר תִּפְאֶרֶת גְּדוּלָּתוֹ, יָמִים רַבִּים שְׁמוֹנִים וּמְאַת יוֹם: וּבִמְלוֹאת הַיָּמִים הָאֵלֶּה עָשָׂה הַמֶּלֶךְ לְכָל הָעָם הַנִּמְצְאִים בְּשׁוּשַׁן הַבִּירָה לְמִגָּדוֹל וְעַד קָטָן מִשְׁתֶּה שִׁבְעַת יָמִים, בַּחֲצַר גִּנַּת בִּיתַן הַמֶּלֶךְ: חוּר כַּרְפַּס וּתְכֵלֶת אָחוּז בְּחַבְלֵי בוּץ וְאַרְגָּמָן עַל גְּלִילֵי כֶסֶף וְעַמּוּדֵי שֵׁשׁ, מִטּוֹת זָהָב וָכֶסֶף עַל רִצְפַת בַּהַט וָשֵׁשׁ וְדַר וְסֹחָרֶת: וְהַשְׁקוֹת בִּכְלֵי זָהָב וְכֵלִים מִכֵּלִים שׁוֹנִים, וְיֵין מַלְכוּת רָב כְּיַד הַמֶּלֶךְ: וְהַשְּׁתִיָּה כַדָּת אֵין אֹנֵס, כִּי כֵן יִסַּד הַמֶּלֶךְ עַל כָּל רַב בֵּיתוֹ לַעֲשׂוֹת כִּרְצוֹן אִישׁ וָאִישׁ: גַּם וַשְׁתִּי הַמַּלְכָּה עָשְׂתָה מִשְׁתֵּה נָשִׁים, בֵּית הַמַּלְכוּת אֲשֶׁר לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: בַּיּוֹם הַשְּׁבִיעִי כְּטוֹב לֵב הַמֶּלֶךְ בַּיָּיִן, אָמַר לִמְהוּמָן בִּזְּתָא חַרְבוֹנָא בִּגְתָא וַאֲבַגְתָא זֵתַר וְכַרְכַּס שִׁבְעַת הַסָּרִיסִים הַמְשָׁרְתִים אֶת פְּנֵי הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: לְהָבִיא אֶת וַשְׁתִּי הַמַּלְכָּה לִפְנֵי הַמֶּלֶךְ בְּכֶתֶר מַלְכוּת, לְהַרְאוֹת הָעַמִּים וְהַשָּׂרִים אֶת יָפְיָהּ, כִּי טוֹבַת מַרְאֶה הִיא: וַתְּמָאֵן הַמַּלְכָּה וַשְׁתִּי לָבוֹא בִּדְבַר הַמֶּלֶךְ אֲשֶׁר בְּיַד הַסָּרִיסִים, וַיִּקְצֹף הַמֶּלֶךְ מְאֹד וַחֲמָתוֹ בָּעֲרָה בוֹ: וַיֹּאמֶר הַמֶּלֶךְ לַחֲכָמִים יֹדְעֵי הָעִתִּים, כִּי כֵן דְּבַר הַמֶּלֶךְ לִפְנֵי כָּל יֹדְעֵי דָּת וָדִין: וְהַקָּרֹב אֵלָיו כַּרְשְׁנָא שֵׁתָר אַדְמָתָא תַרְשִׁישׁ מֶרֶס מַרְסְנָא מְמוּכָן, שִׁבְעַת שָׂרֵי פָּרַס וּמָדַי רֹאֵי פְּנֵי הַמֶּלֶךְ הַיֹּשְׁבִים רִאשֹׁנָה בַּמַּלְכוּת: כְּדָת מַה לַּעֲשׂוֹת בַּמַּלְכָּה וַשְׁתִּי, עַל אֲשֶׁר לֹא עָשְׂתָה אֶת מַאֲמַר הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ בְּיַד הַסָּרִיסִים: וַיֹּאמֶר מְמוּכָן לִפְנֵי הַמֶּלֶךְ וְהַשָּׂרִים, לֹא עַל הַמֶּלֶךְ לְבַדּוֹ עָוְתָה וַשְׁתִּי הַמַּלְכָּה, כִּי עַל כָּל הַשָּׂרִים וְעַל כָּל הָעַמִּים אֲשֶׁר בְּכָל מְדִינוֹת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: כִּי יֵצֵא דְבַר הַמַּלְכָּה עַל כָּל הַנָּשִׁים לְהַבְזוֹת בַּעְלֵיהֶן בְּעֵינֵיהֶן, בְּאָמְרָם הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ אָמַר לְהָבִיא אֶת וַשְׁתִּי הַמַּלְכָּה לְפָנָיו וְלֹא בָאָה: וְהַיּוֹם הַזֶּה תֹּאמַרְנָה שָׂרוֹת פָּרַס וּמָדַי אֲשֶׁר שָׁמְעוּ אֶת דְּבַר הַמַּלְכָּה לְכֹל שָׂרֵי הַמֶּלֶךְ, וּכְדַי בִּזָּיוֹן וָקָצֶף: אִם עַל הַמֶּלֶךְ טוֹב יֵצֵא דְבַר מַלְכוּת מִלְּפָנָיו וְיִכָּתֵב בְּדָתֵי פָרַס וּמָדַי וְלֹא יַעֲבוֹר, אֲשֶׁר לֹא תָבוֹא וַשְׁתִּי לִפְנֵי הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ וּמַלְכוּתָהּ יִתֵּן הַמֶּלֶךְ לִרְעוּתָהּ הַטּוֹבָה מִמֶּנָּה: וְנִשְׁמַע פִּתְגָם הַמֶּלֶךְ אֲשֶׁר יַעֲשֶׂה בְּכָל מַלְכוּתוֹ כִּי רַבָּה הִיא, וְכָל הַנָּשִׁים יִתְּנוּ יְקָר לְבַעְלֵיהֶן לְמִגָּדוֹל וְעַד קָטָן: וַיִּיטַב הַדָּבָר בְּעֵינֵי הַמֶּלֶךְ וְהַשָּׂרִים, וַיַּעַשׂ הַמֶּלֶךְ כִּדְבַר מְמוּכָן: וַיִּשְׁלַח סְפָרִים אֶל כָּל מְדִינוֹת הַמֶּלֶךְ, אֶל מְדִינָה וּמְדִינָה כִּכְתָבָהּ וְאֶל עַם וָעָם כִּלְשׁוֹנוֹ, לִהְיוֹת כָּל אִישׁ שֹׂרֵר בְּבֵיתוֹ וּמְדַבֵּר כִּלְשׁוֹן עַמּוֹ:","cond":["megilatEster"]},{"kind":"header","text":"פרק ב'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ב'","cond":["megilatEster"]},{"kind":"text","text":"אַחַר הַדְּבָרִים הָאֵלֶּה כְּשֹׁךְ חֲמַת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, זָכַר אֶת וַשְׁתִּי וְאֵת אֲשֶׁר עָשָׂתָה וְאֵת אֲשֶׁר נִגְזַר עָלֶיהָ: וַיֹּאמְרוּ נַעֲרֵי הַמֶּלֶךְ מְשָׁרְתָיו, יְבַקְשׁוּ לַמֶּלֶךְ נְעָרוֹת בְּתוּלוֹת טוֹבוֹת מַרְאֶה: וְיַפְקֵד הַמֶּלֶךְ פְּקִידִים בְּכָל מְדִינוֹת מַלְכוּתוֹ, וְיִקְבְּצוּ אֶת כָּל נַעֲרָה בְתוּלָה טוֹבַת מַרְאֶה אֶל שׁוּשַׁן הַבִּירָה אֶל בֵּית הַנָּשִׁים אֶל יַד הֵגֶא סְרִיס הַמֶּלֶךְ שֹׁמֵר הַנָּשִׁים, וְנָתוֹן תַּמְרוּקֵיהֶן: וְהַנַּעֲרָה אֲשֶׁר תִּיטַב בְּעֵינֵי הַמֶּלֶךְ תִּמְלֹךְ תַּחַת וַשְׁתִּי, וַיִּיטַב הַדָּבָר בְּעֵינֵי הַמֶּלֶךְ וַיַּעַשׂ כֵּן:","cond":["megilatEster"]},{"kind":"special","text":"אִישׁ יְהוּדִי הָיָה בְּשׁוּשַׁן הַבִּירָה, וּשְׁמוֹ מָרְדֳּכַי בֶּן יָאִיר בֶּן שִׁמְעִי בֶּן קִישׁ אִישׁ יְמִינִי:","cond":["megilatEster"]},{"kind":"text","text":"אֲשֶׁר הָגְלָה מִירוּשָׁלַיִם עִם הַגֹּלָה אֲשֶׁר הָגְלְתָה עִם יְכָנְיָה מֶלֶךְ יְהוּדָה, אֲשֶׁר הֶגְלָה נְבוּכַדְנֶאצַּר מֶלֶךְ בָּבֶל: וַיְהִי אֹמֵן אֶת הֲדַסָּה הִיא אֶסְתֵּר בַּת דֹּדוֹ כִּי אֵין לָהּ אָב וָאֵם, וְהַנַּעֲרָה יְפַת תֹּאַר וְטוֹבַת מַרְאֶה וּבְמוֹת אָבִיהָ וְאִמָּהּ לְקָחָהּ מָרְדֳּכַי לוֹ לְבַת: וַיְהִי בְּהִשָּׁמַע דְּבַר הַמֶּלֶךְ וְדָתוֹ, וּבְהִקָּבֵץ נְעָרוֹת רַבּוֹת אֶל שׁוּשַׁן הַבִּירָה אֶל יַד הֵגָי, וַתִּלָּקַח אֶסְתֵּר אֶל בֵּית הַמֶּלֶךְ אֶל יַד הֵגַי שֹׁמֵר הַנָּשִׁים: וַתִּיטַב הַנַּעֲרָה בְעֵינָיו וַתִּשָּׂא חֶסֶד לְפָנָיו, וַיְבַהֵל אֶת תַּמְרוּקֶיהָ וְאֶת מָנוֹתֶהָ לָתֵת לָהּ, וְאֵת שֶׁבַע הַנְּעָרוֹת הָרְאֻיוֹת לָתֶת לָהּ מִבֵּית הַמֶּלֶךְ, וַיְשַׁנֶּהָ וְאֶת נַעֲרוֹתֶיהָ לְטוֹב בֵּית הַנָּשִׁים: לֹא הִגִּידָה אֶסְתֵּר אֶת עַמָּהּ וְאֶת מוֹלַדְתָּהּ, כִּי מָרְדֳּכַי צִוָּה עָלֶיהָ אֲשֶׁר לֹא תַגִּיד: וּבְכָל יוֹם וָיוֹם מָרְדֳּכַי מִתְהַלֵּךְ לִפְנֵי חֲצַר בֵּית הַנָּשִׁים, לָדַעַת אֶת שְׁלוֹם אֶסְתֵּר וּמַה יֵּעָשֶׂה בָּהּ: וּבְהַגִּיעַ תֹּר נַעֲרָה וְנַעֲרָה לָבוֹא אֶל הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, מִקֵּץ הֱיוֹת לָהּ כְּדָת הַנָּשִׁים שְׁנֵים עָשָׂר חֹדֶשׁ כִּי כֵּן יִמְלְאוּ יְמֵי מְרוּקֵיהֶן, שִׁשָּׁה חֳדָשִׁים בְּשֶׁמֶן הַמֹּר וְשִׁשָּׁה חֳדָשִׁים בַּבְּשָׂמִים וּבְתַמְרוּקֵי הַנָּשִׁים: וּבָזֶה הַנַּעֲרָה בָּאָה אֶל הַמֶּלֶךְ, אֵת כָּל אֲשֶׁר תֹּאמַר יִנָּתֵן לָהּ לָבוֹא עִמָּהּ מִבֵּית הַנָּשִׁים עַד בֵּית הַמֶּלֶךְ: בָּעֶרֶב הִיא בָאָה וּבַבֹּקֶר הִיא שָׁבָה אֶל בֵּית הַנָּשִׁים שֵׁנִי, אֶל יַד שַׁעֲשְׁגַז סְרִיס הַמֶּלֶךְ שֹׁמֵר הַפִּילַגְשִׁים, לֹא תָבוֹא עוֹד אֶל הַמֶּלֶךְ כִּי אִם חָפֵץ בָּהּ הַמֶּלֶךְ וְנִקְרְאָה בְשֵׁם: וּבְהַגִּיעַ תֹּר אֶסְתֵּר בַּת אֲבִיחַיִל דֹּד מָרְדֳּכַי אֲשֶׁר לָקַח לוֹ לְבַת לָבוֹא אֶל הַמֶּלֶךְ, לֹא בִקְשָׁה דָּבָר כִּי אִם אֶת אֲשֶׁר יֹאמַר הֵגַי סְרִיס הַמֶּלֶךְ שֹׁמֵר הַנָּשִׁים, וַתְּהִי אֶסְתֵּר נֹשֵׂאת חֵן בְּעֵינֵי כָּל רֹאֶיהָ: וַתִּלָּקַח אֶסְתֵּר אֶל הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ אֶל בֵּית מַלְכוּתוֹ בַּחֹדֶשׁ הָעֲשִׂירִי הוּא חֹדֶשׁ טֵבֵת, בִּשְׁנַת שֶׁבַע לְמַלְכוּתוֹ: וַיֶּאֱהַב הַמֶּלֶךְ אֶת אֶסְתֵּר מִכָּל הַנָּשִׁים וַתִּשָּׂא חֵן וָחֶסֶד לְפָנָיו מִכָּל הַבְּתוּלֹת, וַיָּשֶׂם כֶּתֶר מַלְכוּת בְּרֹאשָׁהּ וַיַּמְלִיכֶהָ תַּחַת וַשְׁתִּי: וַיַּעַשׂ הַמֶּלֶךְ מִשְׁתֶּה גָדוֹל לְכָל שָׂרָיו וַעֲבָדָיו, אֵת מִשְׁתֵּה אֶסְתֵּר, וַהֲנָחָה לַמְּדִינוֹת עָשָׂה וַיִּתֵּן מַשְׂאֵת כְּיַד הַמֶּלֶךְ: וּבְהִקָּבֵץ בְּתוּלוֹת שֵׁנִית, וּמָרְדֳּכַי יֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ: אֵין אֶסְתֵּר מַגֶּדֶת מוֹלַדְתָּהּ וְאֶת עַמָּהּ כַּאֲשֶׁר צִוָּה עָלֶיהָ מָרְדֳּכַי, וְאֶת מַאֲמַר מָרְדֳּכַי אֶסְתֵּר עֹשָׂה כַּאֲשֶׁר הָיְתָה בְאָמְנָה אִתּוֹ: בַּיָּמִים הָהֵם, וּמָרְדֳּכַי יֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ, קָצַף בִּגְתָן וָתֶרֶשׁ שְׁנֵי סָרִיסֵי הַמֶּלֶךְ מִשֹּׁמְרֵי הַסַּף וַיְבַקְשׁוּ לִשְׁלֹחַ יָד בַּמֶּלֶךְ אֲחַשְׁוֵרֹשׁ: וַיִּוָּדַע הַדָּבָר לְמָרְדֳּכַי וַיַּגֵּד לְאֶסְתֵּר הַמַּלְכָּה, וַתֹּאמֶר אֶסְתֵּר לַמֶּלֶךְ בְּשֵׁם מָרְדֳּכַי: וַיְבֻקַּשׁ הַדָּבָר וַיִּמָּצֵא וַיִּתָּלוּ שְׁנֵיהֶם עַל עֵץ, וַיִּכָּתֵב בְּסֵפֶר דִּבְרֵי הַיָּמִים לִפְנֵי הַמֶּלֶךְ:","cond":["megilatEster"]},{"kind":"header","text":"פרק ג'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ג'","cond":["megilatEster"]},{"kind":"text","text":"אַחַר הַדְּבָרִים הָאֵלֶּה גִּדַּל הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ אֶת הָמָן בֶּן הַמְּדָתָא הָאֲגָגִי וַיְנַשְּׂאֵהוּ, וַיָּשֶׂם אֶת כִּסְאוֹ מֵעַל כָּל הַשָּׂרִים אֲשֶׁר אִתּוֹ: וְכָל עַבְדֵי הַמֶּלֶךְ אֲשֶׁר בְּשַׁעַר הַמֶּלֶךְ כֹּרְעִים וּמִשְׁתַּחֲוִים לְהָמָן, כִּי כֵן צִוָּה לוֹ הַמֶּלֶךְ, וּמָרְדֳּכַי לֹא יִכְרַע וְלֹא יִשְׁתַּחֲוֶה: וַיֹּאמְרוּ עַבְדֵי הַמֶּלֶךְ אֲשֶׁר בְּשַׁעַר הַמֶּלֶךְ לְמָרְדֳּכַי, מַדּוּעַ אַתָּה עוֹבֵר אֵת מִצְוַת הַמֶּלֶךְ: וַיְהִי כְּאָמְרָם אֵלָיו יוֹם וָיוֹם וְלֹא שָׁמַע אֲלֵיהֶם, וַיַּגִּידוּ לְהָמָן לִרְאוֹת הֲיַעַמְדוּ דִּבְרֵי מָרְדֳּכַי כִּי הִגִּיד לָהֶם אֲשֶׁר הוּא יְהוּדִי: וַיַּרְא הָמָן כִּי אֵין מָרְדֳּכַי כֹּרֵעַ וּמִשְׁתַּחֲוֶה לוֹ, וַיִּמָּלֵא הָמָן חֵמָה: וַיִּבֶז בְּעֵינָיו לִשְׁלֹח יָד בְּמָרְדֳּכַי לְבַדּוֹ כִּי הִגִּידוּ לוֹ אֶת עַם מָרְדֳּכַי, וַיְבַקֵּשׁ הָמָן לְהַשְׁמִיד אֶת כָּל הַיְּהוּדִים אֲשֶׁר בְּכָל מַלְכוּת אֲחַשְׁוֵרוֹשׁ עַם מָרְדֳּכַי: בַּחֹדֶשׁ הָרִאשׁוֹן הוּא חֹדֶשׁ נִיסָן בִּשְׁנַת שְׁתֵּים עֶשְׂרֵה לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, הִפִּיל פּוּר הוּא הַגּוֹרָל לִפְנֵי הָמָן מִיּוֹם לְיוֹם וּמֵחֹדֶשׁ לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר: וַיֹּאמֶר הָמָן לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ יֶשְׁנוֹ עַם אֶחָד מְפֻזָּר וּמְפֹרָד בֵּין הָעַמִּים בְּכֹל מְדִינוֹת מַלְכוּתֶךָ, וְדָתֵיהֶם שֹׁנוֹת מִכָּל עָם וְאֶת דָּתֵי הַמֶּלֶךְ אֵינָם עֹשִׂים וְלַמֶּלֶךְ אֵין שֹׁוֶה לְהַנִּיחָם: אִם עַל הַמֶּלֶךְ טוֹב יִכָּתֵב לְאַבְּדָם, וַעֲשֶׂרֶת אֲלָפִים כִּכַּר כֶּסֶף אֶשְׁקוֹל עַל יְדֵי עֹשֵׂי הַמְּלָאכָה לְהָבִיא אֶל גִּנְזֵי הַמֶּלֶךְ: וַיָּסַר הַמֶּלֶךְ אֶת טַבַּעְתּוֹ מֵעַל יָדוֹ, וַיִּתְּנָהּ לְהָמָן בֶּן הַמְּדָתָא הָאֲגָגִי צֹרֵר הַיְּהוּדִים: וַיֹּאמֶר הַמֶּלֶךְ לְהָמָן הַכֶּסֶף נָתוּן לָךְ, וְהָעָם לַעֲשׂוֹת בּוֹ כַּטּוֹב בְּעֵינֶיךָ: וַיִּקָּרְאוּ סֹפְרֵי הַמֶּלֶךְ בַּחֹדֶשׁ הָרִאשׁוֹן בִּשְׁלוֹשָׁה עָשָׂר יוֹם בּוֹ, וַיִּכָּתֵב כְּכָל אֲשֶׁר צִוָּה הָמָן אֶל אֲחַשְׁדַּרְפְּנֵי הַמֶּלֶךְ וְאֶל הַפַּחוֹת אֲשֶׁר עַל מְדִינָה וּמְדִינָה וְאֶל שָׂרֵי עַם וָעָם, מְדִינָה וּמְדִינָה כִּכְתָבָהּ וְעַם וָעָם כִּלְשׁוֹנוֹ, בְּשֵׁם הַמֶּלֶךְ אֲחַשְׁוֵרֹשׁ נִכְתָּב וְנֶחְתָּם בְּטַבַּעַת הַמֶּלֶךְ: וְנִשְׁלוֹחַ סְפָרִים בְּיַד הָרָצִים אֶל כָּל מְדִינוֹת הַמֶּלֶךְ, לְהַשְׁמִיד לַהֲרֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלוֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: פַּתְשֶׁגֶן הַכְּתָב לְהִנָּתֵן דָּת בְּכָל מְדִינָה וּמְדִינָה גָּלוּי לְכָל הָעַמִּים, לִהְיוֹת עֲתִדִים לַיּוֹם הַזֶּה: הָרָצִים יָצְאוּ דְחוּפִים בִּדְבַר הַמֶּלֶךְ וְהַדָּת נִתְּנָה בְּשׁוּשַׁן הַבִּירָה, וְהַמֶּלֶךְ וְהָמָן יָשְׁבוּ לִשְׁתּוֹת וְהָעִיר שׁוּשָׁן נָבוֹכָה:","cond":["megilatEster"]},{"kind":"header","text":"פרק ד'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ד'","cond":["megilatEster"]},{"kind":"text","text":"וּמָרְדֳּכַי יָדַע אֶת כָּל אֲשֶׁר נַעֲשָׂה וַיִּקְרַע מָרְדֳּכַי אֶת בְּגָדָיו וַיִּלְבַּשׁ שַׂק וָאֵפֶר, וַיֵּצֵא בְּתוֹךְ הָעִיר וַיִּזְעַק זְעָקָה גְדֹלָה וּמָרָה: וַיָּבוֹא עַד לִפְנֵי שַׁעַר הַמֶּלֶךְ, כִּי אֵין לָבוֹא אֶל שַׁעַר הַמֶּלֶךְ בִּלְבוּשׁ שָׂק: וּבְכָל מְדִינָה וּמְדִינָה מְקוֹם אֲשֶׁר דְּבַר הַמֶּלֶךְ וְדָתוֹ מַגִּיעַ, אֵבֶל גָּדוֹל לַיְּהוּדִים וְצוֹם וּבְכִי וּמִסְפֵּד, שַׂק וָאֵפֶר יֻצַּע לָרַבִּים: וַתָּבוֹאנָה נַעֲרוֹת אֶסְתֵּר וְסָרִיסֶיהָ וַיַּגִּידוּ לָהּ וַתִּתְחַלְחַל הַמַּלְכָּה מְאֹד, וַתִּשְׁלַח בְּגָדִים לְהַלְבִּישׁ אֶת מָרְדֳּכַי וּלְהָסִיר שַׂקּוֹ מֵעָלָיו וְלֹא קִבֵּל: וַתִּקְרָא אֶסְתֵּר לַהֲתָךְ מִסָּרִיסֵי הַמֶּלֶךְ אֲשֶׁר הֶעֱמִיד לְפָנֶיהָ וַתְּצַוֵּהוּ עַל מָרְדֳּכַי, לָדַעַת מַה זֶּה וְעַל מַה זֶּה: וַיֵּצֵא הֲתָךְ אֶל מָרְדֳּכַי, אֶל רְחוֹב הָעִיר אֲשֶׁר לִפְנֵי שַׁעַר הַמֶּלֶךְ: וַיַּגֶּד לוֹ מָרְדֳּכַי אֵת כָּל אֲשֶׁר קָרָהוּ, וְאֵת פָּרָשַׁת הַכֶּסֶף אֲשֶׁר אָמַר הָמָן לִשְׁקוֹל עַל גִּנְזֵי הַמֶּלֶךְ בַּיְּהוּדִים לְאַבְּדָם: וְאֶת פַּתְשֶׁגֶן כְּתָב הַדָּת אֲשֶׁר נִתַּן בְּשׁוּשָׁן לְהַשְׁמִידָם נָתַן לוֹ לְהַרְאוֹת אֶת אֶסְתֵּר וּלְהַגִּיד לָהּ, וּלְצַוּוֹת עָלֶיהָ לָבוֹא אֶל הַמֶּלֶךְ לְהִתְחַנֶּן לוֹ וּלְבַקֵּשׁ מִלְּפָנָיו עַל עַמָּהּ: וַיָּבוֹא הֲתָךְ, וַיַּגֵּד לְאֶסְתֵּר אֵת דִּבְרֵי מָרְדֳּכַי: וַתֹּאמֶר אֶסְתֵּר לַהֲתָךְ, וַתְּצַוֵּהוּ אֶל מָרְדֳּכַי: כָּל עַבְדֵי הַמֶּלֶךְ וְעַם מְדִינוֹת הַמֶּלֶךְ יוֹדְעִים אֲשֶׁר כָּל אִישׁ וְאִשָּׁה אֲשֶׁר יָבוֹא אֶל הַמֶּלֶךְ אֶל הֶחָצֵר הַפְּנִימִית אֲשֶׁר לֹא יִקָּרֵא אַחַת דָּתוֹ לְהָמִית, לְבַד מֵאֲשֶׁר יוֹשִׁיט לוֹ הַמֶּלֶךְ אֶת שַׁרְבִיט הַזָּהָב וְחָיָה, וַאֲנִי לֹא נִקְרֵאתִי לָבוֹא אֶל הַמֶּלֶךְ זֶה שְׁלוֹשִׁים יוֹם: וַיַּגִּידוּ לְמָרְדֳּכַי אֵת דִּבְרֵי אֶסְתֵּר: וַיֹּאמֶר מָרְדֳּכַי לְהָשִׁיב אֶל אֶסְתֵּר, אַל תְּדַמִּי בְנַפְשֵׁךְ לְהִמָּלֵט בֵּית הַמֶּלֶךְ מִכָּל הַיְּהוּדִים: כִּי אִם הַחֲרֵשׁ תַּחֲרִישִׁי בָּעֵת הַזֹּאת, רֶוַח וְהַצָּלָה יַעֲמוֹד לַיְּהוּדִים מִמָּקוֹם אַחֵר וְאַתְּ וּבֵית אָבִיךְ תֹּאבֵדוּ, וּמִי יוֹדֵעַ אִם לְעֵת כָּזֹאת הִגַּעַתְּ לַמַּלְכוּת: וַתֹּאמֶר אֶסְתֵּר לְהָשִׁיב אֶל מָרְדֳּכַי: לֵךְ כְּנוֹס אֶת כָּל הַיְּהוּדִים הַנִּמְצְאִים בְּשׁוּשָׁן וְצוּמוּ עָלַי וְאַל תֹּאכְלוּ וְאַל תִּשְׁתּוּ שְׁלֹשֶׁת יָמִים לַיְלָה וָיוֹם, גַּם אֲנִי וְנַעֲרֹתַי אָצוּם כֵּן, וּבְכֵן אָבוֹא אֶל הַמֶּלֶךְ אֲשֶׁר לֹא כַדָּת וְכַאֲשֶׁר אָבַדְתִּי אָבָדְתִּי: וַיַּעֲבֹר מָרְדֳּכַי, וַיַּעַשׂ כְּכֹל אֲשֶׁר צִוְּתָה עָלָיו אֶסְתֵּר:","cond":["megilatEster"]},{"kind":"header","text":"פרק ה'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ה'","cond":["megilatEster"]},{"kind":"text","text":"וַיְהִי בַּיּוֹם הַשְּׁלִישִׁי וַתִּלְבַּשׁ אֶסְתֵּר מַלְכוּת, וַתַּעֲמֹד בַּחֲצַר בֵּית הַמֶּלֶךְ הַפְּנִימִית נֹכַח בֵּית הַמֶּלֶךְ, וְהַמֶּלֶךְ יוֹשֵׁב עַל כִּסֵּא מַלְכוּתוֹ בְּבֵית הַמַּלְכוּת נֹכַח פֶּתַח הַבָּיִת: וַיְהִי כִרְאוֹת הַמֶּלֶךְ אֶת אֶסְתֵּר הַמַּלְכָּה עֹמֶדֶת בֶּחָצֵר נָשְׂאָה חֵן בְּעֵינָיו, וַיּוֹשֶׁט הַמֶּלֶךְ לְאֶסְתֵּר אֶת שַׁרְבִיט הַזָּהָב אֲשֶׁר בְּיָדוֹ, וַתִּקְרַב אֶסְתֵּר וַתִּגַּע בְּרֹאשׁ הַשַּׁרְבִיט: וַיֹּאמֶר לָהּ הַמֶּלֶךְ מַה לָּךְ אֶסְתֵּר הַמַּלְכָּה, וּמַה בַּקָּשָׁתֵךְ עַד חֲצִי הַמַּלְכוּת וְיִנָּתֵן לָךְ: וַתֹּאמֶר אֶסְתֵּר אִם עַל הַמֶּלֶךְ טוֹב, יָבוֹא הַמֶּלֶךְ וְהָמָן הַיּוֹם אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשִׂיתִי לוֹ: וַיֹּאמֶר הַמֶּלֶךְ מַהֲרוּ אֶת הָמָן לַעֲשׂוֹת אֶת דְּבַר אֶסְתֵּר, וַיָּבֹא הַמֶּלֶךְ וְהָמָן אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשְׂתָה אֶסְתֵּר: וַיֹּאמֶר הַמֶּלֶךְ לְאֶסְתֵּר בְּמִשְׁתֵּה הַיַּיִן מַה שְּׁאֵלָתֵךְ וְיִנָּתֵן לָךְ, וּמַה בַּקָּשָׁתֵךְ עַד חֲצִי הַמַּלְכוּת וְתֵעָשׂ: וַתַּעַן אֶסְתֵּר וַתֹּאמַר, שְׁאֵלָתִי וּבַקָּשָׁתִי: אִם מָצָאתִי חֵן בְּעֵינֵי הַמֶּלֶךְ וְאִם עַל הַמֶּלֶךְ טוֹב לָתֵת אֶת שְׁאֵלָתִי וְלַעֲשׂוֹת אֶת בַּקָּשָׁתִי, יָבוֹא הַמֶּלֶךְ וְהָמָן אֶל הַמִּשְׁתֶּה אֲשֶׁר אֶעֱשֶׂה לָהֶם וּמָחָר אֶעֱשֶׂה כִּדְבַר הַמֶּלֶךְ: וַיֵּצֵא הָמָן בַּיּוֹם הַהוּא שָׂמֵחַ וְטוֹב לֵב, וְכִרְאוֹת הָמָן אֶת מָרְדֳּכַי בְּשַׁעַר הַמֶּלֶךְ וְלֹא קָם וְלֹא זָע מִמֶּנּוּ וַיִּמָּלֵא הָמָן עַל מָרְדֳּכַי חֵמָה: וַיִּתְאַפַּק הָמָן וַיָּבוֹא אֶל בֵּיתוֹ, וַיִּשְׁלַח וַיָּבֵא אֶת אֹהֲבָיו וְאֶת זֶרֶשׁ אִשְׁתּוֹ: וַיְסַפֵּר לָהֶם הָמָן אֶת כְּבוֹד עָשְׁרוֹ וְרֹב בָּנָיו, וְאֵת כָּל אֲשֶׁר גִּדְּלוֹ הַמֶּלֶךְ וְאֵת אֲשֶׁר נִשְּׂאוֹ עַל הַשָּׂרִים וְעַבְדֵי הַמֶּלֶךְ: וַיֹּאמֶר הָמָן, אַף לֹא הֵבִיאָה אֶסְתֵּר הַמַּלְכָּה עִם הַמֶּלֶךְ אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשָׂתָה כִּי אִם אוֹתִי, וְגַם לְמָחָר אֲנִי קָרוּא לָהּ עִם הַמֶּלֶךְ: וְכָל זֶה אֵינֶנּוּ שֹׁוֶה לִי, בְּכָל עֵת אֲשֶׁר אֲנִי רֹאֶה אֶת מָרְדֳּכַי הַיְּהוּדִי יוֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ: וַתֹּאמֶר לוֹ זֶרֶשׁ אִשְׁתּוֹ וְכָל אֹהֲבָיו יַעֲשׂוּ עֵץ גָּבֹהַּ חֲמִשִּׁים אַמָּה, וּבַבֹּקֶר אֱמֹר לַמֶּלֶךְ וְיִתְלוּ אֶת מָרְדֳּכַי עָלָיו וּבֹא עִם הַמֶּלֶךְ אֶל הַמִּשְׁתֶּה שָׂמֵחַ, וַיִּיטַב הַדָּבָר לִפְנֵי הָמָן וַיַּעַשׂ הָעֵץ:","cond":["megilatEster"]},{"kind":"header","text":"פרק ו'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ו'","cond":["megilatEster"]},{"kind":"special","text":"בַּלַּיְלָה הַהוּא נָדְדָה שְׁנַת הַמֶּלֶךְ, וַיֹּאמֶר לְהָבִיא אֶת סֵפֶר הַזִּכְרֹנוֹת דִּבְרֵי הַיָּמִים, וַיִּהְיוּ נִקְרָאִים לִפְנֵי הַמֶּלֶךְ:","cond":["megilatEster"]},{"kind":"text","text":"וַיִּמָּצֵא כָתוּב אֲשֶׁר הִגִּיד מָרְדֳּכַי עַל בִּגְתָנָא וָתֶרֶשׁ שְׁנֵי סָרִיסֵי הַמֶּלֶךְ מִשֹּׁמְרֵי הַסַּף אֲשֶׁר בִּקְשׁוּ לִשְׁלֹחַ יָד בַּמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: וַיֹּאמֶר הַמֶּלֶךְ מַה נַּעֲשָׂה יְקָר וּגְדוּלָּה לְמָרְדֳּכַי עַל זֶה, וַיֹּאמְרוּ נַעֲרֵי הַמֶּלֶךְ מְשָׁרְתָיו לֹא נַעֲשָׂה עִמּוֹ דָּבָר: וַיֹּאמֶר הַמֶּלֶךְ מִי בֶחָצֵר, וְהָמָן בָּא לַחֲצַר בֵּית הַמֶּלֶךְ הַחִיצוֹנָה לֵאמֹר לַמֶּלֶךְ לִתְלוֹת אֶת מָרְדֳּכַי עַל הָעֵץ אֲשֶׁר הֵכִין לוֹ: וַיֹּאמְרוּ נַעֲרֵי הַמֶּלֶךְ אֵלָיו הִנֵּה הָמָן עֹמֵד בֶּחָצֵר, וַיֹּאמֶר הַמֶּלֶךְ יָבוֹא: וַיָּבוֹא הָמָן, וַיֹּאמֶר לוֹ הַמֶּלֶךְ מַה לַעֲשׂוֹת בָּאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ, וַיֹּאמֶר הָמָן בְּלִבּוֹ לְמִי יַחְפֹּץ הַמֶּלֶךְ לַעֲשׂוֹת יְקָר יוֹתֵר מִמֶּנִּי: וַיֹּאמֶר הָמָן אֶל הַמֶּלֶךְ, אִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ: יָבִיאוּ לְבוּשׁ מַלְכוּת אֲשֶׁר לָבַשׁ בּוֹ הַמֶּלֶךְ, וְסוּס אֲשֶׁר רָכַב עָלָיו הַמֶּלֶךְ וַאֲשֶׁר נִתַּן כֶּתֶר מַלְכוּת בְּרֹאשׁוֹ: וְנָתוֹן הַלְּבוּשׁ וְהַסּוּס עַל יַד אִישׁ מִשָּׂרֵי הַמֶּלֶךְ הַפַּרְתְּמִים וְהִלְבִּישׁוּ אֶת הָאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ, וְהִרְכִּיבֻהוּ עַל הַסּוּס בִּרְחוֹב הָעִיר וְקָרְאוּ לְפָנָיו כָּכָה יֵעָשֶׂה לָאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ: וַיֹּאמֶר הַמֶּלֶךְ לְהָמָן מַהֵר קַח אֶת הַלְּבוּשׁ וְאֶת הַסּוּס כַּאֲשֶׁר דִּבַּרְתָּ וַעֲשֵׂה כֵן לְמָרְדֳּכַי הַיְּהוּדִי הַיּוֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ, אַל תַּפֵּל דָּבָר מִכֹּל אֲשֶׁר דִּבַּרְתָּ: וַיִּקַּח הָמָן אֶת הַלְּבוּשׁ וְאֶת הַסּוּס וַיַּלְבֵּשׁ אֶת מָרְדֳּכַי, וַיַּרְכִּיבֵהוּ בִּרְחוֹב הָעִיר וַיִּקְרָא לְפָנָיו כָּכָה יֵעָשֶׂה לָאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ: וַיָּשָָב מָרְדֳּכַי אֶל שַׁעַר הַמֶּלֶךְ, וְהָמָן נִדְחַף אֶל בֵּיתוֹ אָבֵל וַחֲפוּי רֹאשׁ: וַיְסַפֵּר הָמָן לְזֶרֶשׁ אִשְׁתּוֹ וּלְכָל אֹהֲבָיו אֵת כָּל אֲשֶׁר קָרָהוּ, וַיֹּאמְרוּ לּוֹ חֲכָמָיו וְזֶרֶשׁ אִשְׁתּוֹ אִם מִזֶּרַע הַיְּהוּדִים מָרְדֳּכַי אֲשֶׁר הַחִלּוֹתָ לִנְפֹּל לְפָנָיו לֹא תוּכַל לוֹ, כִּי נָפוֹל תִּפּוֹל לְפָנָיו: עוֹדָם מְדַבְּרִים עִמּוֹ וְסָרִיסֵי הַמֶּלֶךְ הִגִּיעוּ, וַיַּבְהִלוּ לְהָבִיא אֶת הָמָן אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשְׂתָה אֶסְתֵּר:","cond":["megilatEster"]},{"kind":"header","text":"פרק ז'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ז'","cond":["megilatEster"]},{"kind":"text","text":"וַיָּבֹא הַמֶּלֶךְ וְהָמָן לִשְׁתּוֹת עִם אֶסְתֵּר הַמַּלְכָּה: וַיֹּאמֶר הַמֶּלֶךְ לְאֶסְתֵּר גַּם בַּיּוֹם הַשֵּׁנִי בְּמִשְׁתֵּה הַיַּיִן מַה שְּׁאֵלָתֵךְ אֶסְתֵּר הַמַּלְכָּה וְתִנָּתֵן לָךְ, וּמַה בַּקָּשָׁתֵךְ עַד חֲצִי הַמַּלְכוּת וְתֵעָשׂ: וַתַּעַן אֶסְתֵּר הַמַּלְכָּה וַתֹּאמַר אִם מָצָאתִי חֵן בְּעֵינֶיךָ הַמֶּלֶךְ וְאִם עַל הַמֶּלֶךְ טוֹב, תִּנָּתֶן לִי נַפְשִׁי בִּשְׁאֵלָתִי וְעַמִּי בְּבַקָּשָׁתִי: כִּי נִמְכַּרְנוּ אֲנִי וְעַמִּי לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד, וְאִלּוּ לַעֲבָדִים וְלִשְׁפָחוֹת נִמְכַּרְנוּ הֶחֱרַשְׁתִּי כִּי אֵין הַצָּר שֹׁוֶה בְּנֵזֶק הַמֶּלֶךְ: וַיֹּאמֶר הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ וַיֹּאמֶר לְאֶסְתֵּר הַמַּלְכָּה, מִי הוּא זֶה וְאֵי זֶה הוּא אֲשֶׁר מְלָאוֹ לִבּוֹ לַעֲשׂוֹת כֵּן: וַתֹּאמֶר אֶסְתֵּר אִישׁ צַר וְאוֹיֵב הָמָן הָרָע הַזֶּה, וְהָמָן נִבְעַת מִלִּפְנֵי הַמֶּלֶךְ וְהַמַּלְכָּה: וְהַמֶּלֶךְ קָם בַּחֲמָתוֹ מִמִּשְׁתֵּה הַיַּיִן אֶל גִּנַּת הַבִּיתָן, וְהָמָן עָמַד לְבַקֵּשׁ עַל נַפְשׁוֹ מֵאֶסְתֵּר הַמַּלְכָּה כִּי רָאָה כִּי כָלְתָה אֵלָיו הָרָעָה מֵאֵת הַמֶּלֶךְ: וְהַמֶּלֶךְ שָׁב מִגִּנַּת הַבִּיתָן אֶל בֵּית מִשְׁתֵּה הַיַּיִן וְהָמָן נֹפֵל עַל הַמִּטָּה אֲשֶׁר אֶסְתֵּר עָלֶיהָ, וַיֹּאמֶר הַמֶּלֶךְ הֲגַם לִכְבּוֹשׁ אֶת הַמַּלְכָּה עִמִּי בַּבָּיִת, הַדָּבָר יָצָא מִפִּי הַמֶּלֶךְ וּפְנֵי הָמָן חָפוּ: וַיֹּאמֶר חַרְבוֹנָה אֶחָד מִן הַסָּרִיסִים לִפְנֵי הַמֶּלֶךְ גַּם הִנֵּה הָעֵץ אֲשֶׁר עָשָׂה הָמָן לְמָרְדֳּכַי אֲשֶׁר דִּבֶּר טוֹב עַל הַמֶּלֶךְ עֹמֵד בְּבֵית הָמָן גָּבֹהַּ חֲמִשִּׁים אַמָּה, וַיֹּאמֶר הַמֶּלֶךְ תְּלֻהוּ עָלָיו: וַיִּתְלוּ אֶת הָמָן עַל הָעֵץ אֲשֶׁר הֵכִין לְמָרְדֳּכַי, וַחֲמַת הַמֶּלֶךְ שָׁכָכָה:","cond":["megilatEster"]},{"kind":"header","text":"פרק ח'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ח'","cond":["megilatEster"]},{"kind":"text","text":"בַּיּוֹם הַהוּא נָתַן הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ לְאֶסְתֵּר הַמַּלְכָּה אֶת בֵּית הָמָן צֹרֵר הַיְּהוּדִים, וּמָרְדֳּכַי בָּא לִפְנֵי הַמֶּלֶךְ כִּי הִגִּידָה אֶסְתֵּר מַה הוּא לָהּ: וַיָּסַר הַמֶּלֶךְ אֶת טַבַּעְתּוֹ אֲשֶׁר הֶעֱבִיר מֵהָמָן וַיִּתְּנָהּ לְמָרְדֳּכַי, וַתָּשֶׂם אֶסְתֵּר אֶת מָרְדֳּכַי עַל בֵּית הָמָן: וַתּוֹסֶף אֶסְתֵּר וַתְּדַבֵּר לִפְנֵי הַמֶּלֶךְ וַתִּפֹּל לִפְנֵי רַגְלָיו, וַתֵּבְךְּ וַתִּתְחַנֶּן לוֹ לְהַעֲבִיר אֶת רָעַת הָמָן הָאֲגָגִי וְאֵת מַחֲשַׁבְתּוֹ אֲשֶׁר חָשַׁב עַל הַיְּהוּדִים: וַיּוֹשֶׁט הַמֶּלֶךְ לְאֶסְתֵּר אֵת שַׁרְבִט הַזָּהָב, וַתָּקָם אֶסְתֵּר וַתַּעֲמֹד לִפְנֵי הַמֶּלֶךְ: וַתֹּאמֶר אִם עַל הַמֶּלֶךְ טוֹב וְאִם מָצָאתִי חֵן לְפָנָיו וְכָשֵׁר הַדָּבָר לִפְנֵי הַמֶּלֶךְ וְטוֹבָה אֲנִי בְּעֵינָיו, יִכָּתֵב לְהָשִׁיב אֶת הַסְּפָרִים מַחֲשֶׁבֶת הָמָן בֶּן הַמְּדָתָא הָאֲגָגִי אֲשֶׁר כָּתַב לְאַבֵּד אֶת הַיְּהוּדִים אֲשֶׁר בְּכָל מְדִינוֹת הַמֶּלֶךְ: כִּי אֵיכָכָה אוּכַל וְרָאִיתִי בָּרָעָה אֲשֶׁר יִמְצָא אֶת עַמִּי, וְאֵיכָכָה אוּכַל וְרָאִיתִי בְּאָבְדַן מוֹלַדְתִּי: וַיֹּאמֶר הַמֶּלֶךְ אֲחַשְׁוֵרֹשׁ לְאֶסְתֵּר הַמַּלְכָּה וּלְמָרְדֳּכַי הַיְּהוּדִי, הִנֵּה בֵית הָמָן נָתַתִּי לְאֶסְתֵּר וְאֹתוֹ תָּלוּ עַל הָעֵץ עַל אֲשֶׁר שָׁלַח יָדוֹ בַּיְּהוּדִים: וְאַתֶּם כִּתְבוּ עַל הַיְּהוּדִים כַּטּוֹב בְּעֵינֵיכֶם בְּשֵׁם הַמֶּלֶךְ וְחִתְמוּ בְּטַבַּעַת הַמֶּלֶךְ, כִּי כְתָב אֲשֶׁר נִכְתָּב בְּשֵׁם הַמֶּלֶךְ וְנַחְתּוֹם בְּטַבַּעַת הַמֶּלֶךְ אֵין לְהָשִׁיב: וַיִּקָּרְאוּ סֹפְרֵי הַמֶּלֶךְ בָּעֵת הַהִיא בַּחֹדֶשׁ הַשְּׁלִישִׁי הוּא חֹדֶשׁ סִיוָן בִּשְׁלוֹשָׁה וְעֶשְׂרִים בּוֹ, וַיִּכָּתֵב כְּכָל אֲשֶׁר צִוָּה מָרְדֳּכַי אֶל הַיְּהוּדִים וְאֶל הָאֲחַשְׁדַּרְפְּנִים וְהַפַּחוֹת וְשָׂרֵי הַמְּדִינוֹת אֲשֶׁר מֵהֹדּוּ וְעַד כּוּשׁ, שֶׁבַע וְעֶשְׂרִים וּמֵאָה מְדִינָה, מְדִינָה וּמְדִינָה כִּכְתָבָהּ וְעַם וָעָם כִּלְשֹׁנוֹ, וְאֶל הַיְּהוּדִים כִּכְתָבָם וְכִלְשׁוֹנָם: וַיִּכְתֹּב בְּשֵׁם הַמֶּלֶךְ אֲחַשְׁוֵרֹשׁ וַיַּחְתֹּם בְּטַבַּעַת הַמֶּלֶךְ, וַיִּשְׁלַח סְפָרִים בְּיַד הָרָצִים בַּסּוּסִים רֹכְבֵי הָרֶכֶשׁ הָאֲחַשְׁתְּרָנִים בְּנֵי הָרַמָּכִים: אֲשֶׁר נָתַן הַמֶּלֶךְ לַיְּהוּדִים אֲשֶׁר בְּכָל עִיר וָעִיר לְהִקָּהֵל וְלַעֲמֹד עַל נַפְשָׁם, לְהַשְׁמִיד וְלַהֲרֹג וּלְאַבֵּד אֶת כָּל חֵיל עַם וּמְדִינָה הַצָּרִים אֹתָם טַף וְנָשִׁים, וּשְׁלָלָם לָבוֹז: בְּיוֹם אֶחָד בְּכָל מְדִינוֹת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, בִּשְׁלוֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר: פַּתְשֶׁגֶן הַכְּתָב לְהִנָּתֵן דָּת בְּכָל מְדִינָה וּמְדִינָה גָּלוּי לְכָל הָעַמִּים, וְלִהְיוֹת הַיְּהוּדִים עֲתִידִים לַיּוֹם הַזֶּה לְהִנָּקֵם מֵאֹיְבֵיהֶם: הָרָצִים רֹכְבֵי הָרֶכֶשׁ הָאֲחַשְׁתְּרָנִים יָצְאוּ מְבֹהָלִים וּדְחוּפִים בִּדְבַר הַמֶּלֶךְ, וְהַדָּת נִתְּנָה בְּשׁוּשַׁן הַבִּירָה:","cond":["megilatEster"]},{"kind":"special","text":"וּמָרְדֳּכַי יָצָא מִלִּפְנֵי הַמֶּלֶךְ בִּלְבוּשׁ מַלְכוּת תְּכֵלֶת וָחוּר וַעֲטֶרֶת זָהָב גְּדוֹלָה וְתַכְרִיךְ בּוּץ וְאַרְגָּמָן, וְהָעִיר שׁוּשָׁן צָהֲלָה וְשָׂמֵחָה: לַיְּהוּדִים הָיְתָה אוֹרָה וְשִׂמְחָה, וְשָׂשֹׂן וִיקָר:","cond":["megilatEster"]},{"kind":"text","text":"וּבְכָל מְדִינָה וּמְדִינָה וּבְכָל עִיר וָעִיר, מְקוֹם אֲשֶׁר דְּבַר הַמֶּלֶךְ וְדָתוֹ מַגִּיעַ, שִׂמְחָה וְשָׂשׂוֹן לַיְּהוּדִים מִשְׁתֶּה וְיוֹם טוֹב, וְרַבִּים מֵעַמֵּי הָאָרֶץ מִתְיַהֲדִים כִּי נָפַל פַּחַד הַיְּהוּדִים עֲלֵיהֶם:","cond":["megilatEster"]},{"kind":"header","text":"פרק ט'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ט'","cond":["megilatEster"]},{"kind":"text","text":"וּבִשְׁנֵים עָשָׂר חֹדֶשׁ הוּא חֹדֶשׁ אֲדָר בִּשְׁלוֹשָׁה עָשָׂר יוֹם בּוֹ אֲשֶׁר הִגִּיעַ דְּבַר הַמֶּלֶךְ וְדָתוֹ לְהֵעָשׂוֹת, בַּיּוֹם אֲשֶׁר שִׂבְּרוּ אֹיְבֵי הַיְּהוּדִים לִשְׁלוֹט בָּהֶם וְנַהֲפוֹךְ הוּא אֲשֶׁר יִשְׁלְטוּ הַיְּהוּדִים הֵמָּה בְּשֹׂנְאֵיהֶם: נִקְהֲלוּ הַיְּהוּדִים בְּעָרֵיהֶם בְּכָל מְדִינוֹת הַמֶּלֶךְ אֳחַשְׁוֵרוֹשׁ לִשְׁלֹחַ יָד בִּמְבַקְשֵׁי רָעָתָם, וְאִישׁ לֹא עָמַד לִפְנֵיהֶם כִּי נָפַל פַּחְדָּם עַל כָּל הָעַמִּים: וְכָל שָׂרֵי הַמְּדִינוֹת וְהָאֲחַשְׁדַּרְפְּנִים וְהַפַּחוֹת וְעֹשֵׂי הַמְּלָאכָה אֲשֶׁר לַמֶּלֶךְ מְנַשְּׂאִים אֶת הַיְּהוּדִים, כִּי נָפַל פַּחַד מָרְדֳּכַי עֲלֵיהֶם: כִּי גָדוֹל מָרְדֳּכַי בְּבֵית הַמֶּלֶךְ וְשָׁמְעוֹ הוֹלֵךְ בְּכָל הַמְּדִינוֹת, כִּי הָאִישׁ מָרְדֳּכַי הוֹלֵךְ וְגָדוֹל: וַיַּכּוּ הַיְּהוּדִים בְּכָל אֹיְבֵיהֶם מַכַּת חֶרֶב וְהֶרֶג וְאַבְדָן, וַיַּעֲשׂוּ בְשֹׂנְאֵיהֶם כִּרְצוֹנָם: וּבְשׁוּשַׁן הַבִּירָה הָרְגוּ הַיְּהוּדִים וְאַבֵּד חֲמֵשׁ מֵאוֹת אִישׁ: וְאֵת פַּרְשַׁנְדָּתָא וְאֵת דַּלְפוֹן וְאֵת אַסְפָּתָא: וְאֵת פּוֹרָתָא וְאֵת אֲדַלְיָא וְאֵת אֲרִידָתָא: וְאֵת פַּרְמַשְׁתָּא וְאֵת אֲרִיסַי וְאֵת אֲרִדַי וְאֵת וַיְזָתָא: עֲשֶׂרֶת בְּנֵי הָמָן בֶּן הַמְּדָתָא צֹרֵר הַיְּהוּדִים הָרָגוּ, וּבַבִּזָּה לֹא שָׁלְחוּ אֶת יָדָם: בַּיּוֹם הַהוּא בָּא מִסְפַּר הַהֲרוּגִים בְּשׁוּשַׁן הַבִּירָה לִפְנֵי הַמֶּלֶךְ: וַיֹּאמֶר הַמֶּלֶךְ לְאֶסְתֵּר הַמַּלְכָּה בְּשׁוּשַׁן הַבִּירָה הָרְגוּ הַיְּהוּדִים וְאַבֵּד חֲמֵשׁ מֵאוֹת אִישׁ וְאֵת עֲשֶׂרֶת בְּנֵי הָמָן, בִּשְׁאָר מְדִינוֹת הַמֶּלֶךְ מֶה עָשׂוּ, וּמַה שְּׁאֵלָתֵךְ וְיִנָּתֵן לָךְ וּמַה בַּקָּשָׁתֵךְ עוֹד וְתֵעָשׂ: וַתֹּאמֶר אֶסְתֵּר אִם עַל הַמֶּלֶךְ טוֹב, יִנָּתֵן גַּם מָחָר לַיְּהוּדִים אֲשֶׁר בְּשׁוּשָׁן לַעֲשׂוֹת כְּדָת הַיּוֹם, וְאֵת עֲשֶׂרֶת בְּנֵי הָמָן יִתְלוּ עַל הָעֵץ: וַיֹּאמֶר הַמֶּלֶךְ לְהֵעָשׂוֹת כֵּן וַתִּנָּתֵן דָּת בְּשׁוּשָׁן, וְאֵת עֲשֶׂרֶת בְּנֵי הָמָן תָּלוּ: וַיִּקָּהֲלוּ הַיְּהוּדִים אֲשֶׁר בְּשׁוּשָׁן גַּם בְּיוֹם אַרְבָּעָה עָשָׂר לְחֹדֶשׁ אֲדָר וַיַּהַרְגוּ בְשׁוּשָׁן שְׁלֹשׁ מֵאוֹת אִישׁ, וּבַבִּזָּה לֹא שָׁלְחוּ אֶת יָדָם: וּשְׁאָר הַיְּהוּדִים אֲשֶׁר בִּמְדִינוֹת הַמֶּלֶךְ נִקְהֲלוּ וְעָמֹד עַל נַפְשָׁם וְנוֹחַ מֵאֹיְבֵיהֶם וְהָרֹג בְּשֹׂנְאֵיהֶם חֲמִשָּׁה וְשִׁבְעִים אָלֶף, וּבַבִּזָּה לֹא שָׁלְחוּ אֶת יָדָם: בְּיוֹם שְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ אֲדָר, וְנוֹחַ בְּאַרְבָּעָה עָשָׂר בּוֹ וְעָשֹׂה אֹתוֹ יוֹם מִשְׁתֶּה וְשִׂמְחָה: וְהַיְּהוּדִים אֲשֶׁר בְּשׁוּשָׁן נִקְהֲלוּ בִּשְׁלֹשָׁה עָשָׂר בּוֹ וּבְאַרְבָּעָה עָשָׂר בּוֹ, וְנוֹחַ בַּחֲמִשָּׁה עָשָׂר בּוֹ וְעָשֹׂה אֹתוֹ יוֹם מִשְׁתֶּה וְשִׂמְחָה: עַל כֵּן הַיְּהוּדִים הַפְּרָזִים הַיֹּשְׁבִים בְּעָרֵי הַפְּרָזוֹת, עֹשִׂים אֵת יוֹם אַרְבָּעָה עָשָׂר לְחֹדֶשׁ אֲדָר שִׂמְחָה וּמִשְׁתֶּה וְיוֹם טוֹב, וּמִשְׁלוֹחַ מָנוֹת אִישׁ לְרֵעֵהוּ: וַיִּכְתֹּב מָרְדֳּכַי אֶת הַדְּבָרִים הָאֵלֶּה, וַיִּשְׁלַח סְפָרִים אֶל כָּל הַיְּהוּדִים אֲשֶׁר בְּכָל מְדִינוֹת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ הַקְּרוֹבִים וְהָרְחוֹקִים: לְקַיֵּם עֲלֵיהֶם, לִהְיוֹת עֹשִׂים אֵת יוֹם אַרְבָּעָה עָשָׂר לְחֹדֶשׁ אֲדָר וְאֵת יוֹם חֲמִשָּׁה עָשָׂר בּוֹ, בְּכָל שָׁנָה וְשָׁנָה: כַּיָּמִים אֲשֶׁר נָחוּ בָהֶם הַיְּהוּדִים מֵאוֹיְבֵיהֶם, וְהַחֹדֶשׁ אֲשֶׁר נֶהְפַּךְ לָהֶם מִיָּגוֹן לְשִׂמְחָה וּמֵאֵבֶל לְיוֹם טוֹב, לַעֲשׂוֹת אוֹתָם יְמֵי מִשְׁתֶּה וְשִׂמְחָה וּמִשְׁלוֹחַ מָנוֹת אִישׁ לְרֵעֵהוּ וּמַתָּנוֹת לָאֶבְיוֹנִים: וְקִבֵּל הַיְּהוּדִים אֵת אֲשֶׁר הֵחֵלּוּ לַעֲשׂוֹת, וְאֵת אֲשֶׁר כָּתַב מָרְדֳּכַי אֲלֵיהֶם: כִּי הָמָן בֶּן הַמְּדָתָא הָאֲגָגִי צֹרֵר כָּל הַיְּהוּדִים חָשַׁב עַל הַיְּהוּדִים לְאַבְּדָם, וְהִפִּיל פּוּר הוּא הַגּוֹרָל לְהֻמָּם וּלְאַבְּדָם: וּבְבֹאָהּ לִפְנֵי הַמֶּלֶךְ, אָמַר עִם הַסֵּפֶר יָשׁוּב מַחֲשַׁבְתּוֹ הָרָעָה אֲשֶׁר חָשַׁב עַל הַיְּהוּדִים עַל רֹאשׁוֹ, וְתָלוּ אֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ: עַל כֵּן קָרְאוּ לַיָּמִים הָאֵלֶּה פוּרִים עַל שֵׁם הַפּוּר, עַל כֵּן עַל כָּל דִּבְרֵי הָאִגֶּרֶת הַזֹּאת, וּמָה רָאוּ עַל כָּכָה וּמָה הִגִּיעַ אֲלֵיהֶם: קִיְּמוּ וְקִבְּלוּ הַיְּהוּדִים עֲלֵיהֶם וְעַל זַרְעָם וְעַל כָּל הַנִּלְוִים עֲלֵיהֶם וְלֹא יַעֲבוֹר, לִהְיוֹת עֹשִׂים אֵת שְׁנֵי הַיָּמִים הָאֵלֶּה כִּכְתָבָם וְכִזְמַנָּם, בְּכָל שָׁנָה וְשָׁנָה: וְהַיָּמִים הָאֵלֶּה נִזְכָּרִים וְנַעֲשִׂים בְּכָל דּוֹר וָדוֹר מִשְׁפָּחָה וּמִשְׁפָּחָה מְדִינָה וּמְדִינָה וְעִיר וָעִיר, וִימֵי הַפּוּרִים הָאֵלֶּה לֹא יַעַבְרוּ מִתּוֹךְ הַיְּהוּדִים וְזִכְרָם לֹא יָסוּף מִזַּרְעָם: וַתִּכְתֹּב אֶסְתֵּר הַמַּלְכָּה בַת אֲבִיחַיִל וּמָרְדֳּכַי הַיְּהוּדִי אֶת כָּל תֹּקֶף, לְקַיֵּם אֵת אִגֶּרֶת הַפּוּרִים הַזֹּאת הַשֵּׁנִית: וַיִּשְׁלַח סְפָרִים אֶל כָּל הַיְּהוּדִים, אֶל שֶׁבַע וְעֶשְׂרִים וּמֵאָה מְדִינָה מַלְכוּת אֲחַשְׁוֵרוֹשׁ, דִּבְרֵי שָׁלוֹם וֶאֱמֶת: לְקַיֵּם אֵת יְמֵי הַפֻּרִים הָאֵלֶּה בִּזְמַנֵּיהֶם כַּאֲשֶׁר קִיַּם עֲלֵיהֶם מָרְדֳּכַי הַיְּהוּדִי וְאֶסְתֵּר הַמַּלְכָּה וְכַאֲשֶׁר קִיְּמוּ עַל נַפְשָׁם וְעַל זַרְעָם, דִּבְרֵי הַצֹּמוֹת וְזַעֲקָתָם: וּמַאֲמַר אֶסְתֵּר קִיַּם דִּבְרֵי הַפֻּרִים הָאֵלֶּה, וְנִכְתָּב בַּסֵּפֶר:","cond":["megilatEster"]},{"kind":"header","text":"פרק י'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק י'","cond":["megilatEster"]},{"kind":"text","text":"וַיָּשֶׂם הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ מַס עַל הָאָרֶץ וְאִיֵּי הַיָּם: וְכָל מַעֲשֵׂה תָקְפּוֹ וּגְבוּרָתוֹ, וּפָרָשַׁת גְּדֻלַּת מָרְדֳּכַי אֲשֶׁר גִּדְּלוֹ הַמֶּלֶךְ, הֲלוֹא הֵם כְּתוּבִים עַל סֵפֶר דִּבְרֵי הַיָּמִים לְמַלְכֵי מָדַי וּפָרָס:","cond":["megilatEster"]},{"kind":"special","text":"כִּי מָרְדֳּכַי הַיְּהוּדִי מִשְׁנֶה לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ וְגָדוֹל לַיְּהוּדִים וְרָצוּי לְרֹב אֶחָיו, דֹּרֵשׁ טוֹב לְעַמּוֹ וְדֹבֵר שָׁלוֹם לְכָל זַרְעוֹ:","cond":["megilatEster"]},{"kind":"header","text":"ברכת הרב את ריבנו","cond":["megilatEster"]},{"kind":"instruction","text":"ברכת הרב את ריבנו מברכים גם ביום וגם בלילה, ומברכים אותה רק בציבור של עשרה. ברכה זו מברך רק החזן הקורא את המגילה לאחר שכרך את כל המגילה.","cond":["megilatEster"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הָרָב אֶת רִיבֵנוּ, וְהַדָּן אֶת דִּינֵנוּ, וְהַנּוֹקֵם אֶת נִקְמָתֵנוּ, וְהַמְשַׁלֵּם גְּמוּל לְכָל אוֹיְבֵי נַפְשֵׁנוּ, וְהַנִּפְרָע לָנוּ מִצָּרֵינוּ. בָּרוּךְ אַתָּה יהוה, הַנִּפְרָע לְעַמּוֹ יִשְׂרָאֵל מִכָּל צָרֵיהֶם, הָאֵל הַמּוֹשִׁיעַ.","cond":["megilatEster"]},{"kind":"header","text":"אשר הניא","cond":["megilatEster"]},{"kind":"instruction","text":"אשר הניא\n\nבשחרית מתחילים משושנת יעקב. ויש נוהגים לומר \"אשר הניא\" אף בשחרית, אם אין אומרים פיוטים בחזרת הש\"ץ.","cond":["megilatEster"]},{"kind":"text","text":"אֲשֶׁר הֵנִיא עֲצַת גּוֹיִם, וַיָּפֶר מַחְשְׁבוֹת עֲרוּמִים.\nבְּקוּם עָלֵינוּ אָדָם רָשָׁע, נֵצֶר זָדוֹן מִזֶּרַע עֲמָלֵק.\nגָּאָה בְעָשְׁרוֹ וְכָרָה לוֹ בּוֹר, וּגְדֻלָּתוֹ יָקְשָׁה לּוֹ לָכֶד.\nדִּמָּה בְנַפְשׁוֹ לִלְכֹּד וְנִלְכַּד, בִּקֵּשׁ לְהַשְׁמִיד וְנִשְׁמַד מְהֵרָה.\nהָמָן הוֹדִיעַ אֵיבַת אֲבוֹתָיו, וְעוֹרֵר שִׂנְאַת אַחִים לַבָּנִים.\nוְלֹא זָכַר רַחֲמֵי שָׁאוּל, כִּי בְחֶמְלָתוֹ עַל אֲגָג נוֹלַד אוֹיֵב.\nזָמַם רָשָׁע לְהַכְרִית צַדִּיק, וְנִלְכַּד טָמֵא בִּידֵי טָהוֹר.\nחֶסֶד גָּבַר עַל שִׁגְגַת אָב, וְרָשָׁע הוֹסִיף חֵטְא עַל חֲטָאָיו.\nטָמַן בְּלִבּוֹ מַחְשְׁבוֹת עֲרוּמָיו, וַיִּתְמַכֵּר לַעֲשׂוֹת רָעָה.\nיָדוֹ שָׁלַח בִּקְדוֹשֵׁי אֵל, כַּסְפּוֹ נָתַן לְהַכְרִית זִכְרָם.\nכִּרְאוֹת מָרְדֳּכַי כִּי יָצָא קֶצֶף, וְדָתֵי הָמָן נִתְּנוּ בְשׁוּשָׁן.\nלָבַשׁ שַׂק וְקָשַׁר מִסְפֵּד, וְגָזַר צוֹם וַיֵּשֶׁב עַל הָאֵפֶר.\nמִי זֶה יַעֲמֹד לְכַפֵּר שְׁגָגָה, וְלִמְחֹל חַטַּאת עֲוׂן אֲבוֹתֵינוּ.\nנֵץ פָּרַח מִלּוּלָב, הֵן הֲדַסָּה עָמְדָה לְעוֹרֵר יְשֵׁנִים.\nסָרִיסֶיהָ הִבְהִילוּ לְהָמָן, לְהַשְׁקוֹתוֹ יֵין חֲמַת תַּנִּינִים.\nעָמַד בְּעָשְׁרוֹ וְנָפַל בְּרִשְׁעוֹ, עָשָׂה לוֹ עֵץ וְנִתְלָה עָלָיו.\nפִּיהֶם פָּתְחוּ כָָּל יוֹשְׁבֵי תֵבֵל, כִּי פוּר הָמָן נֶהְפַּךְ לְפוּרֵנוּ.\nצַדִּיק נֶחֱלַץ מִיַּד רָשָׁע, אוֹיֵב נִתַּן תַּחַת נַפְשׁוֹ.\nקִיְּמוּ עֲלֵיהֶם לַעֲשׂוֹת פּוּרִים, וְלִשְׂמֹחַ בְּכָל שָׁנָה וְשָׁנָה.\nרָאִיתָ אֶת תְּפִלַּת מָרְדֳּכַי וְאֶסְתֵּר, הָמָן וּבָנָיו עַל הָעֵץ תָּלִיתָ.","cond":["megilatEster"]},{"kind":"header","text":"שושנת יעקב","cond":["megilatEster"]},{"kind":"text","text":"שׁוֹשַׁנַּת יַעֲקֹב צָהֲלָה וְשָׂמֵחָה, בִּרְאוֹתָם יַחַד תְּכֵלֶת מָרְדֳּכָי.\nתְּשׁוּעָתָם הָיִיתָ לָנֶצַח, וְתִקְוָתָם בְּכָל דּוֹר וָדוֹר.\nלְהוֹדִיעַ שֶׁכָּל קֹוֶיךָ לֹא יֵבֹשׁוּ, וְלֹא יִכָּלְמוּ לָנֶצַח כָּל הַחוֹסִים בָּךְ.\nאָרוּר הָמָן אֲשֶׁר בִּקֵשׁ לְאַבְּדִי. בָּרוּךְ מָרְדֳּכַי הַיְּהוּדִי.\nאֲרוּרָה זֶרֶשׁ אֵשֶׁת מַפְחִידִי. בְּרוּכָה אֶסְתֵּר [מְגִנָּה] בַּעֲדִי.\nאֲרוּרִים כָּל הָרְשָׁעִים. בְּרוּכִים כָּל הַצַּדִּיקִים.\nוְגַם חַרְבוֹנָה זָכוּר לַטּוֹב.","cond":["megilatEster"]},{"kind":"header","text":"אשרי ובא לציון","cond":[]},{"kind":"instruction","text":"אשרי ובא לציון","cond":[]},{"kind":"text","text":"אַשְׁרֵי יוֹשְׁבֵי בֵיתֶךָ עוֹד יְהַלְלוּךָ סֶּלָה:\nאַשְׁרֵי הָעָם שֶׁכָּכָה לּוֹ אַשְׁרֵי הָעָם שֶׁיהוה אֱלֹהָיו:\nתְּהִלָּה לְדָוִד, אֲרוֹמִמְךָ אֱלוֹהַי הַמֶּלֶךְ וַאֲבָרְכָה שִׁמְךָ לְעוֹלָם וָעֶד:\nבְּכָל יוֹם אֲבָרְכֶךָּ וַאֲהַלְלָה שִׁמְךָ לְעוֹלָם וָעֶד:\nגָּדוֹל יהוה וּמְהֻלָּל מְאֹד וְלִגְדֻלָּתוֹ אֵין חֵקֶר:\nדּוֹר לְדוֹר יְשַׁבַּח מַעֲשֶׂיךָ וּגְבוּרֹתֶיךָ יַגִּידוּ:\nהֲדַר כְּבוֹד הוֹדֶךָ וְדִבְרֵי נִפְלְאוֹתֶיךָ אָשִׂיחָה:\nוֶעֱזוּז נוֹרְאֹתֶיךָ יֹאמֵרוּ וּגְדוּלָּתְךָ אֲסַפְּרֶנָּה:\nזֵכֶר רַב טוּבְךָ יַבִּיעוּ וְצִדְקָתְךָ יְרַנֵּנוּ:","cond":[]},{"kind":"text","text":"חַנּוּן וְרַחוּם יהוה אֶרֶךְ אַפַּיִם וּגְדָל חָסֶד:\nטוֹב יהוה לַכֹּל וְרַחֲמָיו עַל כָּל מַעֲשָׂיו:\nיוֹדוּךָ יהוה כָּל מַעֲשֶׂיךָ וַחֲסִידֶיךָ יְבָרְכוּכָה:\nכְּבוֹד מַלְכוּתְךָ יֹאמֵרוּ וּגְבוּרָתְךָ יְדַבֵּרוּ:\nלְהוֹדִיעַ לִבְנֵי הָאָדָם גְּבוּרֹתָיו וּכְבוֹד הֲדַר מַלְכוּתוֹ:\nמַלְכוּתְךָ מַלְכוּת כָּל עֹלָמִים וּמֶמְשַׁלְתְּךָ בְּכָל דּוֹר וָדוֹר:\nסוֹמֵךְ יהוה לְכָל הַנֹּפְלִים וְזוֹקֵף לְכָל הַכְּפוּפִים:\nעֵינֵי כֹל אֵלֶיךָ יְשַׂבֵּרוּ וְאַתָּה נוֹתֵן לָהֶם אֶת אָכְלָם בְּעִתּוֹ:","cond":[]},{"kind":"text","text":"פּוֹתֵחַ אֶת יָדֶךָ וּמַשְׂבִּיעַ לְכָל חַי רָצוֹן:\nצַדִּיק יהוה בְּכָל דְּרָכָיו וְחָסִיד בְּכָל מַעֲשָׂיו:\nקָרוֹב יהוה לְכָל קֹרְאָיו לְכֹל אֲשֶׁר יִקְרָאֻהוּ בֶאֱמֶת:\nרְצוֹן יְרֵאָיו יַעֲשֶׂה וְאֶת שַׁוְעָתָם יִשְׁמַע וְיוֹשִׁיעֵם:\nשׁוֹמֵר יהוה אֶת כָּל אֹהֲבָיו וְאֵת כָּל הָרְשָׁעִים יַשְׁמִיד:\nתְּהִלַּת יהוה יְדַבֶּר פִּי וִיבָרֵךְ כָּל בָּשָׂר שֵׁם קָדְשׁוֹ לְעוֹלָם וָעֶד:\nוַאֲנַחְנוּ נְבָרֵךְ יָהּ מֵעַתָּה וְעַד עוֹלָם הַלְלוּיָהּ:","cond":[]},{"kind":"text","text":"לַמְנַצֵּחַ מִזְמוֹר לְדָוִד: יַעַנְךָ יהוה בְּיוֹם צָרָה, יְשַׂגֶּבְךָ שֵׁם אֱלֹהֵי יַעֲקֹב: יִשְׁלַח עֶזְרְךָ מִקֹּדֶשׁ, וּמִצִּיּוֹן יִסְעָדֶךָּ: יִזְכֹּר כָּל מִנְחֹתֶךָ, וְעוֹלָתְךָ יְדַשְּׁנֶה סֶלָה: יִתֶּן לְךָ כִלְבָבֶךָ, וְכָל עֲצָתְךָ יְמַלֵּא: נְרַנְּנָה בִּישׁוּעָתֶךָ וּבְשֵׁם אֱלֹהֵינוּ נִדְגֹּל, יְמַלֵּא יהוה כָּל מִשְׁאֲלוֹתֶיךָ: עַתָּה יָדַעְתִּי כִּי הוֹשִׁיעַ יהוה מְשִׁיחוֹ, יַעֲנֵהוּ מִשְּׁמֵי קָדְשׁוֹ, בִּגְבֻרוֹת יֵשַׁע יְמִינוֹ: אֵלֶּה בָרֶכֶב וְאֵלֶּה בַסּוּסִים, וַאֲנַחְנוּ בְּשֵׁם יהוה אֱלֹהֵינוּ נַזְכִּיר: הֵמָּה כָּרְעוּ וְנָפָלוּ, וַאֲנַחְנוּ קַּמְנוּ וַנִּתְעוֹדָד: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":["lamnatzeach"]},{"kind":"instruction","text":"ובא לציון","cond":[]},{"kind":"text","text":"וּבָא לְצִיּוֹן גּוֹאֵל, וּלְשָׁבֵי פֶשַׁע בְּיַעֲקֹב, נְאֻם יהוה:","cond":[]},{"kind":"text","text":"וַאֲנִי זֹאת בְּרִיתִי אוֹתָם, אָמַר יהוה, רוּחִי אֲשֶׁר עָלֶיךָ וּדְבָרַי אֲשֶׁר שַׂמְתִּי בְּפִיךָ, לֹא יָמוּשׁוּ מִפִּיךָ וּמִפִּי זַרְעֲךָ וּמִפִּי זֶרַע זַרְעֲךָ, אָמַר יהוה, מֵעַתָּה וְעַד עוֹלָם:","cond":["noTishaaBeav"]},{"kind":"header","text":"ואתה קדוש","cond":[]},{"kind":"text","text":"וְאַתָּה קָדוֹשׁ יוֹשֵׁב תְּהִלּוֹת יִשְׂרָאֵל: וְקָרָא זֶה אֶל זֶה וְאָמַר: קָדוֹשׁ, קָדוֹשׁ, קָדוֹשׁ יהוה צְבָאוֹת, מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ: וּמְקַבְּלִין דֵּין מִן דֵּין וְאָמְרִין: קַדִּישׁ בִּשְׁמֵי מֵרוֹמַא עִלָאַה בֵּית שְׁכִינְתֵּהּ, קַדִּישׁ עַל אַרְעָא עוֹבַד גְּבוּרְתֵּהּ, קַדִּישׁ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא, יהוה צְבָאוֹת מַלְיָא כָל אַרְעָא זִיו יְקָרֵהּ. וַתִּשָּׂאֵנִי רוּחַ, וָאֶשְׁמַע אַחֲרַי קוֹל רַעַשׁ גָּדוֹל: בָּרוּךְ כְּבוֹד יהוה מִמְּקוֹמוֹ: וּנְטָלַתְנִי רוּחָא, וּשְׁמָעִית בַּתְרַי קַל זִיעַ שַׂגִּיא דִמְשַׁבְּחִין וְאָמְרִין: בְּרִיךְ יְקָרָא דַיהוה מֵאֲתָר בֵּית שְׁכִינְתֵּהּ. יהוה יִמְלֹךְ לְעוֹלָם וָעֶד: יהוה מַלְכוּתֵיהּ קָאֵים לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\n\nיהוה אֱלֹהֵי אַבְרָהָם יִצְחָק וְיִשְׂרָאֵל אֲבוֹתֵינוּ, שָׁמְרָה זֹּאת לְעוֹלָם, לְיֵצֶר מַחְשְׁבוֹת לְבַב עַמֶּךָ, וְהָכֵן לְבָבָם אֵלֶיךָ: וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית, וְהִרְבָּה לְהָשִׁיב אַפּוֹ, וְלֹא יָעִיר כָּל חֲמָתוֹ: כִּי אַתָּה יהוה טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קוֹרְאֶיךָ: צִדְקָתְךָ צֶּדֶק לְעוֹלָם, וְתוֹרָתְךָ אֱמֶת: תִּתֵּן אֱמֶת לְיַעֲקֹב, חֶסֶד לְאַבְרָהָם, אֲשֶׁר נִשְׁבַּעְתָּ לַאֲבֹתֵינוּ מִימֵי קֶדֶם: בָּרוּךְ אֲדֹנָי יוֹם יוֹם, יַעֲמָס לָנוּ הָאֵל יְשׁוּעָתֵנוּ, סֶלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב, סֶלָה: יהוה צְבָאוֹת אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ: בָּרוּךְ הוּא אֱלֹהֵינוּ שֶׁבְּרָאָנוּ לִכְבוֹדוֹ, וְהִבְדִּילָנוּ מִן הַתּוֹעִים, וְנָתַן לָנוּ תּוֹרַת אֱמֶת, וְחַיֵּי עוֹלָם נָטַע בְּתוֹכֵנוּ. הוּא יִפְתַּח לִבֵּנוּ בְּתוֹרָתוֹ, וְיָשֵׂם בְּלִבֵּנוּ אַהֲבָתוֹ וְיִרְאָתוֹ וְלַעֲשׂוֹת רְצוֹנוֹ וּלְעָבְדוֹ בְּלֵבָב שָׁלֵם. לְמַעַן לֹא נִיגַע לָרִיק, וְלֹא נֵלֵד לַבֶּהָלָה. יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁנִּשְׁמֹר חֻקֶּיךָ בָּעוֹלָם הַזֶּה, וְנִזְכֶּה וְנִחְיֶה וְנִרְאֶה וְנִירַשׁ טוֹבָה וּבְרָכָה לִשְׁנֵי יְמוֹת הַמָּשִׁיחַ וּלְחַיֵּי הָעוֹלָם הַבָּא. לְמַעַן יְזַמֶּרְךָ כָבוֹד וְלֹא יִדֹּם, יהוה אֱלֹהַי לְעוֹלָם אוֹדֶךָּ: בָּרוּךְ הַגֶּבֶר אֲשֶׁר יִבְטַח בַּיהוה, וְהָיָה יהוה מִבְטַחוֹ: בִּטְחוּ בַיהוה עֲדֵי עַד, כִּי בְּיָהּ יהוה צוּר עוֹלָמִים: וְיִבְטְחוּ בְךָ יוֹדְעֵי שְׁמֶךָ, כִּי לֹא עָזַבְתָּ דֹּרְשֶׁיךָ יהוה: יהוה חָפֵץ לְמַעַן צִדְקוֹ, יַגְדִּיל תּורָה וְיַאְדִּיר:","cond":[]},{"kind":"instruction","text":"חצי קדיש","cond":["musaf"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":["musaf"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["musaf","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["musaf","ayt"]},{"kind":"header","text":"מוסף","cond":["musaf"]},{"kind":"instruction","text":"ברוב הקהילות חולצים את התפילין לפני תפילת מוסף בגלל קדושת \"כתר\". אמנם בנוסח אשכנז לא אומרים קדושת כתר, אבל בכל זאת פשט המנהג גם לקהילות המתפללות בנוסח אשכנז, ומי שנמצא בקהילה שבה חולצים את התפילין לא ישנה ויחלוץ גם.","cond":["musaf","rh"]},{"kind":"instruction","text":"תפילת העמידה","cond":["musaf"]},{"kind":"text","text":"כִּי שֵׁם יהוה אֶקְרָא, הָבוּ גֹדֶל לֵאלֹהֵינוּ:\nאֲדֹנָי, שְׂפָתַי תִּפְתָּח, וּפִי יַגִּיד תְּהִלָּתֶךָ:","cond":["musaf"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק, וֵאלֹהֵי יַעֲקֹב, הָאֵל הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, וְקוֹנֵה הַכֹּל, וְזוֹכֵר חַסְדֵי אָבוֹת, וּמֵבִיא גוֹאֵל לִבְנֵי בְנֵיהֶם לְמַעַן שְׁמוֹ בְּאַהֲבָה.","cond":["musaf"]},{"kind":"special","text":"זָכְרֵנוּ לְחַיִּים, מֶלֶךְ חָפֵץ בַּחַיִּים, וְכָתְבֵנוּ בְּסֵפֶר הַחַיִּים, לְמַעַנְךָ אֱלֹהִים חַיִּים.","cond":["musaf","ayt"]},{"kind":"text","text":"מֶלֶךְ עוֹזֵר וּמוֹשִׁיעַ וּמָגֵן. בָּרוּךְ אַתָּה יהוה, מָגֵן אַבְרָהָם.","cond":["musaf"]},{"kind":"text","text":"אַתָּה גִּבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֵּה מֵתִים אַתָּה רַב לְהוֹשִׁיעַ,","cond":["musaf"]},{"kind":"summer","text":"מוֹרִיד הַטָּל,","cond":["musaf","summerTal"]},{"kind":"winter","text":"מַשִּׁיב הָרוּחַ וּמוֹרִיד הַגֶּשֶׁם,","cond":["musaf","winterTal"]},{"kind":"text","text":"מְכַלְכֵּל חַיִּים בְּחֶסֶד, מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים, סוֹמֵךְ נוֹפְלִים, וְרוֹפֵא חוֹלִים וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמוּנָתוֹ לִישֵׁנֵי עָפָר. מִי כָמוֹךָ בַּעַל גְּבוּרוֹת וּמִי דּוֹמֶה לָךְ, מֶלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִיחַ יְשׁוּעָה.","cond":["musaf"]},{"kind":"special","text":"מִי כָמוֹךָ אַב הָרַחֲמִים, זוֹכֵר יְצוּרָיו לְחַיִּים בְּרַחֲמִים.","cond":["musaf","ayt"]},{"kind":"text","text":"וְנֶאֱמָן אַתָּה לְהַחֲיוֹת מֵתִים. בָּרוּךְ אַתָּה יהוה, מְחַיֵּה הַמֵּתִים.","cond":["musaf"]},{"kind":"text","text":"אַתָּה קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ וּקְדוֹשִׁים בְּכָל יוֹם יְהַלְלוּךָ סֶּלָה.","cond":["musaf"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הָאֵל הַקָּדוֹשׁ.","cond":["musaf","noayt"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יהוה, הַמֶּלֶךְ הַקָּדוֹשׁ.","cond":["musaf","ayt"]},{"kind":"text","text":"רָאשֵׁי חֳדָשִׁים לְעַמְּךָ נָתָתָּ, זְמַן כַּפָּרָה לְכָל תּוֹלְדוֹתָם, בִּהְיוֹתָם מַקְרִיבִים לְפָנֶיךָ זִבְחֵי רָצוֹן, וּשְׂעִירֵי חַטָּאת לְכַפֵּר בַּעֲדָם, זִכָּרוֹן לְכֻלָּם יִהְיוּ, וּתְשׁוּעַת נַפְשָׁם מִיַּד שׂוֹנֵא. מִזְבֵּחַ חָדָשׁ בְּצִיּוֹן תָּכִין, וְעוֹלַת רֹאשׁ חֹדֶשׁ נַעֲלֶה עָלָיו, וּשְׂעִירֵי עִזִּים נַעֲשֶׂה בְרָצוֹן, וּבַעֲבוֹדַת בֵּית הַמִּקְדָּשׁ נִשְׂמַח כֻּלָּנוּ, וּבְשִׁירֵי דָּוִד עַבְדְּךָ הַנִּשְׁמָעִים בְּעִירֶךָ, הָאֲמוּרִים לִפְנֵי מִזְבְּחֶךָ, אַהֲבַת עוֹלָם תָּבִיא לָהֶם וּבְרִית אָבוֹת לַבָּנִים תִּזְכּוֹר. וַהֲבִיאֵנוּ לְצִיּוֹן עִירְךָ בְּרִנָּה, וְלִירוּשָׁלַיִם בֵּית מִקְדָּשְׁךָ בְּשִׂמְחַת עוֹלָם, וְשָׁם נַעֲשֶׂה לְפָנֶיךָ אֶת קָרְבְּנוֹת חוֹבוֹתֵינוּ, תְּמִידִים כְּסִדְרָם וּמוּסָפִים כְּהִלְכָתָם, וְאֶת מוּסַף יוֹם רֹאשׁ הַחֹדֶשׁ הַזֶּה נַעֲשֶׂה וְנַקְרִיב לְפָנֶיךָ בְּאַהֲבָה כְּמִצְוַת רְצוֹנֶךָ, כְּמוֹ שֶׁכָּתַבְתָּ עָלֵינוּ בְּתוֹרָתֶךָ עַל יְדֵי מֹשֶׁה עַבְדֶּךָ מִפִּי כְבוֹדֶךָ, כָּאָמוּר: וּבְרָאשֵׁי חָדְשֵׁיכֶם תַּקְרִיבוּ עוֹלָה לַיהוה, פָּרִים בְּנֵי בָקָר שְׁנַיִם וְאַיִל אֶחָד, כְּבָשִׂים בְּנֵי שָׁנָה שִׁבְעָה, תְּמִימִם: וּמִנְחָתָם וְנִסְכֵּיהֶם כִּמְדֻבָּר: שְׁלשָׁה עֶשְׂרֹנִים לַפָּר, וּשְׁנֵי עֶשְׂרֹנִים לָאָיִל, וְעִשָּׂרוֹן לַכֶּבֶשׂ, וְיַיִן כְּנִסְכּוֹ, וְשָׂעִיר לְכַפֵּר, וּשְׁנֵי תְמִידִים כְּהִלְכָתָם.\n\nאֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, חַדֵּשׁ עָלֵינוּ אֶת הַחֹדֶשׁ הַזֶּה לְטוֹבָה וְלִבְרָכָה, לְשָׂשׂוֹן וּלְשִׂמְחָה, לִישׁוּעָה וּלְנֶחָמָה, לְפַרְנָסָה וּלְכַלְכָּלָה, לְחַיִּים וּלְשָׁלוֹם, לִמְחִילַת חֵטְא וְלִסְלִיחַת עָווֹן.","cond":["musaf","rh"]},{"kind":"text","text":"וּלְכַפָּרַת פָּשַׁע.","cond":["musaf","rh","kaparatPasha"]},{"kind":"text","text":"כִּי בְעַמְּךָ יִשְׂרָאֵל בָּחַרְתָּ מִכָּל הָאֻמּוֹת, וְחֻקֵּי רָאשֵׁי חֳדָשִׁים לָהֶם קָבָעְתָּ. בָּרוּךְ אַתָּה יהוה, מְקַדֵּשׁ יִשְׂרָאֵל וְרָאשֵׁי חֳדָשִׁים.","cond":["musaf","rh"]},{"kind":"text","text":"אַתָּה בְחַרְתָּנוּ מִכָּל הָעַמִּים, אָהַבְתָּ אוֹתָנוּ וְרָצִיתָ בָּנוּ, וְרוֹמַמְתָּנוּ מִכָּל הַלְּשׁוֹנוֹת וְקִדַּשְׁתָּנוּ בְּמִצְוׂתֶיךָ, וְקֵרַבְתָּנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶךָ, וְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ עָלֵינוּ קָרָאתָ. וַתִּתֶּן לָנוּ יהוה אֱלֹהֵינוּ בְּאַהֲבָה מוֹעֲדִים לְשִׂמְחָה, חַגִּים וּזְמַנִּים לְשָׂשׂוֹן אֶת יוֹם","cond":["musaf","pesach"]},{"kind":"text","text":"חַג הַמַּצּוֹת הַזֶּה, זְמַן חֵרוּתֵנוּ","cond":["musaf","pesach","pesach"]},{"kind":"text","text":"חַג הַסֻּכּוֹת הַזֶּה, זְמַן שִׂמְחָתֵנוּ","cond":["musaf","pesach","sucot"]},{"kind":"text","text":"מִקְרָא קֹדֶשׁ, זֵכֶר לִיצִיאַת מִצְרָיִם.\n\nוּמִפְּנֵי חֲטָאֵינוּ גָּלִינוּ מֵאַרְצֵנוּ, וְנִתְרַחַקְנוּ מֵעַל אַדְמָתֵנוּ, וְאֵין אֲנַחְנוּ יְכוֹלִים לַעֲלוֹת וְלֵרָאוֹת וּלְהִשְׁתַּחֲווֹת לְפָנֶיךָ, וְלַעֲשׂוֹת חוֹבוֹתֵינוּ בְּבֵית בְּחִירָתֶךָ, בַּבַּיִת הַגָּדוֹל וְהַקָּדוֹשׁ שֶׁנִּקְרָא שִׁמְךָ עָלָיו, מִפְּנֵי הַיָּד שֶׁנִּשְׁתַּלְּחָה בְּמִקְדָּשֶׁךָ. יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן, שֶׁתָּשׁוּב וּתְרַחֵם עָלֵינוּ וְעַל מִקְדָּשְׁךָ בְּרַחֲמֶיךָ הָרַבִּים, וְתִבְנֵהוּ מְהֵרָה וּתְגַדֵּל כְּבוֹדוֹ. אָבִינוּ מַלְכֵּנוּ, גַּלֵּה כְּבוֹד מַלְכוּתְךָ עָלֵינוּ מְהֵרָה, וְהוֹפַע וְהִנָּשֵׂא עָלֵינוּ לְעֵינֵי כָּל חָי, וְקָרֵב פְּזוּרֵינוּ מִבֵּין הַגּוֹיִם, וּנְפוּצוֹתֵינוּ כַּנֵּס מִיַּרְכְּתֵי אָרֶץ. וַהֲבִיאֵנוּ לְצִיּוֹן עִירְךָ בְּרִנָּה, וְלִירוּשָׁלַיִם בֵּית מִקְדָּשְׁךָ בְּשִׂמְחַת עוֹלָם, וְשָׁם נַעֲשֶׂה לְפָנֶיךָ אֶת קָרְבְּנוֹת חוֹבוֹתֵינוּ תְּמִידִים כְּסִדְרָם וּמוּסָפִים כְּהִלְכָתָם, וְאֶת מוּסַף יוֹם","cond":["musaf","pesach"]},{"kind":"text","text":"חַג הַמַּצּוֹת הַזֶּה","cond":["musaf","pesach","pesach"]},{"kind":"text","text":"חַג הַסֻּכּוֹת הַזֶּה","cond":["musaf","pesach","sucot"]},{"kind":"text","text":"נַעֲשֶׂה וְנַקְרִיב לְפָנֶיךָ בְּאַהֲבָה כְּמִצְוַת רְצוֹנֶךָ, כְּמוֹ שֶׁכָּתַבְתָּ עָלֵינוּ בְּתוֹרָתֶךָ עַל יְדֵי מֹשֶׁה עַבְדֶּךָ מִפִּי כְבוֹדֶךָ, כָּאָמוּר:","cond":["musaf","pesach"]},{"kind":"text","text":"וְהִקְרַבְתֶּם אִשֶּׁה עֹלָה לַיהוה, פָּרִים בְּנֵי בָקָר שְׁנַיִם, וְאַיִל אֶחָד, וְשִׁבְעָה כְבָשִׂים בְּנֵי שָׁנָה, תְּמִימִם יִהְיוּ לָכֶם:\nוּמִנְחָתָם וְנִסְכֵּיהֶם כִּמְדֻבָּר: שְׁלֹשָׁה עֶשְׂרֹנִים לַפָּר, וּשְׁנֵי עֶשְׂרֹנִים לָאָיִל, וְעִשָּׂרוֹן לַכֶּבֶשׂ, וְיַיִן כְּנִסְכּוֹ, וְשָׂעִיר לְכַפֵּר, וּשְׁנֵי תְמִידִים כְּהִלְכָתָם.","cond":["musaf","pesach","pesach"]},{"kind":"text","text":":-:-","cond":["musaf","pesach","sucot"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן רַחֵם עָלֵינוּ, טוֹב וּמֵטִיב הִדָּרֶשׁ לָנוּ, שׁוּבָה אֵלֵינוּ בַּהֲמוֹן רַחֲמֶיךָ, בִּגְלַל אָבוֹת שֶׁעָשׂוּ רְצוֹנֶךָ. בְּנֵה בֵיתְךָ כְּבַתְּחִלָּה, וְכוֹנֵן מִקְדָּשְׁךָ עַל מְכוֹנוֹ, וְהַרְאֵנוּ בְּבִנְיָנוֹ וְשַׂמְּחֵנוּ בְּתִקּוּנוֹ, וְהָשֵׁב כֹּהֲנִים לַעֲבוֹדָתָם וּלְוִיִּם לְשִׁירָם וּלְזִמְרָם, וְהָשֵׁב יִשְׂרָאֵל לִנְוֵיהֶם. וְשָׁם נַעֲלֶה וְנֵרָאֶה וְנִשְׁתַּחֲוֶה לְפָנֶיךָ בְּשָׁלֹשׁ פַּעֲמֵי רְגָלֵינוּ כַּכָּתוּב בְּתוֹרָתֶךָ: שָׁלֹשׁ פְּעָמִים בַּשָּׁנָה יֵרָאֶה כָל זְכוּרְךָ אֶת פְּנֵי יהוה אֱלֹהֶיךָ בַּמָּקום אֲשֶׁר יִבְחָר, בְּחַג הַמַּצּוֹת, וּבְחַג הַשָּׁבֻעוֹת, וּבְחַג הַסֻּכּוֹת, וְלא יֵרָאֶה אֶת פְּנֵי יהוה רֵיקָם: אִישׁ כְּמַתְּנַת יָדוֹ, כְּבִרְכַּת יהוה אֱלֹהֶיךָ אֲשֶׁר נָתַן לָךְ:\n\nוְהַשִּׂיאֵנוּ יהוה אֱלֹהֵינוּ אֶת בִּרְכַּת מוֹעֲדֶיךָ, לְחַיִּים וּלְשָׁלוֹם, לְשִׂמְחָה וּלְשָׂשׂוֹן, כַּאֲשֶׁר רָצִיתָ וְאָמַרְתָּ לְבָרְכֵנוּ. קַדְּשֵׁנוּ בְּמִצְוׂתֶיךָ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתֶךָ, שַׂבְּעֵנוּ מִטּוּבֶךָ, וְשַׂמְּחֵנוּ בִּישׁוּעָתֶךָ, וְטַהֵר לִבֵּנוּ לְעָבְדְּךָ בֶּאֱמֶת, וְהַנְחִילֵנוּ יהוה אֱלֹהֵינוּ בְּשִׂמְחָה וּבְשָׂשׂוֹן מוֹעֲדֵי קָדְשֶׁךָ, וְיִשְׂמְחוּ בְךָ יִשְׂרָאֵל מְקַדְּשֵׁי שְׁמֶךָ. בָּרוּךְ אַתָּה יהוה, מְקַדֵּשׁ יִשְׂרָאֵל וְהַזְּמַנִּים.","cond":["musaf","pesach"]},{"kind":"text","text":"אַתָּה בְחַרְתָּנוּ מִכָּל הָעַמִּים, אָהַבְתָּ אוֹתָנוּ וְרָצִיתָ בָּנוּ, וְרוֹמַמְתָּנוּ מִכָּל הַלְּשׁוֹנוֹת וְקִדַּשְׁתָּנוּ בְּמִצְוׂתֶיךָ, וְקֵרַבְתָּנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶךָ, וְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ עָלֵינוּ קָרָאתָ. וַתִּתֶּן לָנוּ יהוה אֱלֹהֵינוּ בְּאַהֲבָה מוֹעֲדִים לְשִׂמְחָה, חַגִּים וּזְמַנִּים לְשָׂשׂוֹן אֶת יוֹם","cond":["musaf","sucot"]},{"kind":"text","text":"חַג הַמַּצּוֹת הַזֶּה, זְמַן חֵרוּתֵנוּ","cond":["musaf","sucot","pesach"]},{"kind":"text","text":"חַג הַסֻּכּוֹת הַזֶּה, זְמַן שִׂמְחָתֵנוּ","cond":["musaf","sucot","sucot"]},{"kind":"text","text":"מִקְרָא קֹדֶשׁ, זֵכֶר לִיצִיאַת מִצְרָיִם.\n\nוּמִפְּנֵי חֲטָאֵינוּ גָּלִינוּ מֵאַרְצֵנוּ, וְנִתְרַחַקְנוּ מֵעַל אַדְמָתֵנוּ, וְאֵין אֲנַחְנוּ יְכוֹלִים לַעֲלוֹת וְלֵרָאוֹת וּלְהִשְׁתַּחֲווֹת לְפָנֶיךָ, וְלַעֲשׂוֹת חוֹבוֹתֵינוּ בְּבֵית בְּחִירָתֶךָ, בַּבַּיִת הַגָּדוֹל וְהַקָּדוֹשׁ שֶׁנִּקְרָא שִׁמְךָ עָלָיו, מִפְּנֵי הַיָּד שֶׁנִּשְׁתַּלְּחָה בְּמִקְדָּשֶׁךָ. יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן, שֶׁתָּשׁוּב וּתְרַחֵם עָלֵינוּ וְעַל מִקְדָּשְׁךָ בְּרַחֲמֶיךָ הָרַבִּים, וְתִבְנֵהוּ מְהֵרָה וּתְגַדֵּל כְּבוֹדוֹ. אָבִינוּ מַלְכֵּנוּ, גַּלֵּה כְּבוֹד מַלְכוּתְךָ עָלֵינוּ מְהֵרָה, וְהוֹפַע וְהִנָּשֵׂא עָלֵינוּ לְעֵינֵי כָּל חָי, וְקָרֵב פְּזוּרֵינוּ מִבֵּין הַגּוֹיִם, וּנְפוּצוֹתֵינוּ כַּנֵּס מִיַּרְכְּתֵי אָרֶץ. וַהֲבִיאֵנוּ לְצִיּוֹן עִירְךָ בְּרִנָּה, וְלִירוּשָׁלַיִם בֵּית מִקְדָּשְׁךָ בְּשִׂמְחַת עוֹלָם, וְשָׁם נַעֲשֶׂה לְפָנֶיךָ אֶת קָרְבְּנוֹת חוֹבוֹתֵינוּ תְּמִידִים כְּסִדְרָם וּמוּסָפִים כְּהִלְכָתָם, וְאֶת מוּסַף יוֹם","cond":["musaf","sucot"]},{"kind":"text","text":"חַג הַמַּצּוֹת הַזֶּה","cond":["musaf","sucot","pesach"]},{"kind":"text","text":"חַג הַסֻּכּוֹת הַזֶּה","cond":["musaf","sucot","sucot"]},{"kind":"text","text":"נַעֲשֶׂה וְנַקְרִיב לְפָנֶיךָ בְּאַהֲבָה כְּמִצְוַת רְצוֹנֶךָ, כְּמוֹ שֶׁכָּתַבְתָּ עָלֵינוּ בְּתוֹרָתֶךָ עַל יְדֵי מֹשֶׁה עַבְדֶּךָ מִפִּי כְבוֹדֶךָ, כָּאָמוּר:","cond":["musaf","sucot"]},{"kind":"text","text":"וְהִקְרַבְתֶּם אִשֶּׁה עֹלָה לַיהוה, פָּרִים בְּנֵי בָקָר שְׁנַיִם, וְאַיִל אֶחָד, וְשִׁבְעָה כְבָשִׂים בְּנֵי שָׁנָה, תְּמִימִם יִהְיוּ לָכֶם:\nוּמִנְחָתָם וְנִסְכֵּיהֶם כִּמְדֻבָּר: שְׁלֹשָׁה עֶשְׂרֹנִים לַפָּר, וּשְׁנֵי עֶשְׂרֹנִים לָאָיִל, וְעִשָּׂרוֹן לַכֶּבֶשׂ, וְיַיִן כְּנִסְכּוֹ, וְשָׂעִיר לְכַפֵּר, וּשְׁנֵי תְמִידִים כְּהִלְכָתָם.","cond":["musaf","sucot","pesach"]},{"kind":"text","text":":-:-","cond":["musaf","sucot","sucot"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן רַחֵם עָלֵינוּ, טוֹב וּמֵטִיב הִדָּרֶשׁ לָנוּ, שׁוּבָה אֵלֵינוּ בַּהֲמוֹן רַחֲמֶיךָ, בִּגְלַל אָבוֹת שֶׁעָשׂוּ רְצוֹנֶךָ. בְּנֵה בֵיתְךָ כְּבַתְּחִלָּה, וְכוֹנֵן מִקְדָּשְׁךָ עַל מְכוֹנוֹ, וְהַרְאֵנוּ בְּבִנְיָנוֹ וְשַׂמְּחֵנוּ בְּתִקּוּנוֹ, וְהָשֵׁב כֹּהֲנִים לַעֲבוֹדָתָם וּלְוִיִּם לְשִׁירָם וּלְזִמְרָם, וְהָשֵׁב יִשְׂרָאֵל לִנְוֵיהֶם. וְשָׁם נַעֲלֶה וְנֵרָאֶה וְנִשְׁתַּחֲוֶה לְפָנֶיךָ בְּשָׁלֹשׁ פַּעֲמֵי רְגָלֵינוּ כַּכָּתוּב בְּתוֹרָתֶךָ: שָׁלֹשׁ פְּעָמִים בַּשָּׁנָה יֵרָאֶה כָל זְכוּרְךָ אֶת פְּנֵי יהוה אֱלֹהֶיךָ בַּמָּקום אֲשֶׁר יִבְחָר, בְּחַג הַמַּצּוֹת, וּבְחַג הַשָּׁבֻעוֹת, וּבְחַג הַסֻּכּוֹת, וְלא יֵרָאֶה אֶת פְּנֵי יהוה רֵיקָם: אִישׁ כְּמַתְּנַת יָדוֹ, כְּבִרְכַּת יהוה אֱלֹהֶיךָ אֲשֶׁר נָתַן לָךְ:\n\nוְהַשִּׂיאֵנוּ יהוה אֱלֹהֵינוּ אֶת בִּרְכַּת מוֹעֲדֶיךָ, לְחַיִּים וּלְשָׁלוֹם, לְשִׂמְחָה וּלְשָׂשׂוֹן, כַּאֲשֶׁר רָצִיתָ וְאָמַרְתָּ לְבָרְכֵנוּ. קַדְּשֵׁנוּ בְּמִצְוׂתֶיךָ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתֶךָ, שַׂבְּעֵנוּ מִטּוּבֶךָ, וְשַׂמְּחֵנוּ בִּישׁוּעָתֶךָ, וְטַהֵר לִבֵּנוּ לְעָבְדְּךָ בֶּאֱמֶת, וְהַנְחִילֵנוּ יהוה אֱלֹהֵינוּ בְּשִׂמְחָה וּבְשָׂשׂוֹן מוֹעֲדֵי קָדְשֶׁךָ, וְיִשְׂמְחוּ בְךָ יִשְׂרָאֵל מְקַדְּשֵׁי שְׁמֶךָ. בָּרוּךְ אַתָּה יהוה, מְקַדֵּשׁ יִשְׂרָאֵל וְהַזְּמַנִּים.","cond":["musaf","sucot"]},{"kind":"text","text":"רְצֵה יהוה אֱלֹהֵינוּ בְּעַמְּךָ יִשְׂרָאֵל וּבִתְפִלָּתָם, וְהָשֵׁב אֶת הָעֲבוֹדָה לִדְבִיר בֵּיתֶךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם, בְּאַהֲבָה תְקַבֵּל בְּרָצוֹן. וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּךָ. וְתֶחֱזֶינָה עֵינֵינוּ בְּשׁוּבְךָ לְצִיּוֹן בְּרַחֲמִים. בָּרוּךְ אַתָּה יהוה, הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן.","cond":["musaf"]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שָׁאַתָּה הוּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ לְעוֹלָם וָעֶד. צוּר חַיֵּינוּ, מָגֵן יִשְׁעֵנוּ אַתָּה הוּא לְדוֹר וָדוֹר. נוֹדֶה לְּךָ וּנְסַפֵּר תְּהִלָּתֶךָ עַל חַיֵּינוּ הַמְּסוּרִים בְּיָדֶךָ, וְעַל נִשְׁמוֹתֵינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּיךָ שֶׁבְּכָל יוֹם עִמָּנוּ, וְעַל נִפְלְאוֹתֶיךָ וְטוֹבוֹתֶיךָ שֶׁבְּכָל עֵת, עֶרֶב וָבֹקֶר וְצָהֳרָיִם. הַטּוֹב כִּי לֹא כָלוּ רַחֲמֶיךָ, וְהַמְרַחֵם כִּי לֹא תַמּוּ חֲסָדֶיךָ. מֵעוֹלָם קִוִּינוּ לָךְ.","cond":["musaf"]},{"kind":"special","text":"עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מַתִּתְיָהוּ בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְהַשְׁכִּיחָם תּוֹרָתֶךָ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנֶךָ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּטְמֵאִים בְּיַד טְהוֹרִים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, וּלְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמֶךָ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כֵּן בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ לְהוֹדוֹת וּלְהַלֵּל לְשִׁמְךָ הַגָּדוֹל.","cond":["musaf","chanuka"]},{"kind":"special","text":"עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים, מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ, וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ, וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְּרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ (, וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה).","cond":["musaf","purim"]},{"kind":"text","text":"וְעַל כֻּלָּם יִתְבָּרַךְ וְיִתְרוֹמַם שִׁמְךָ מַלְכֵּנוּ תָּמִיד לְעוֹלָם וָעֶד.","cond":["musaf"]},{"kind":"special","text":"וּכְתֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶךָ.","cond":["musaf","ayt"]},{"kind":"text","text":"וְכֹל הַחַיִּים יוֹדוּךָ סֶּלָה, וִיהַלְלוּ אֶת שִׁמְךָ בֶּאֱמֶת, הָאֵל יְשׁוּעָתֵנוּ וְעֶזְרָתֵנוּ סֶלָה. בָּרוּך אַתָּה יהוה, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת.","cond":["musaf"]},{"kind":"text","text":"שִׂים שָׁלוֹם טוֹבָה וּבְרָכָה, חֵן וָחֶסֶד וְרַחֲמִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל עַמֶּךָ, בָּרְכֵנוּ אָבִינוּ כֻּלָּנוּ כְּאֶחָד בְּאוֹר פָּנֶיךָ, כִּי בְאוֹר פָּנֶיךָ נָתַתָּ לָּנוּ יהוה אֱלֹהֵינוּ תּוֹרַת חַיִּים וְאַהֲבַת חֶסֶד, וּצְדָקָה וּבְרָכָה וְרַחֲמִים וְחַיִּים וְשָׁלוֹם, וְטוֹב בְּעֵינֶיךָ לְבָרֵךְ אֶת עַמְּךָ יִשְׂרָאֵל בְּכָל עֵת וּבְכָל שָׁעָה בִּשְׁלוֹמֶךָ.","cond":["musaf"]},{"kind":"special","text":"בְּסֵפֶר חַיִּים, בְּרָכָה וְשָׁלוֹם, וּפַרְנָסָה טוֹבָה, נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ, אֲנַחְנוּ וְכָל עַמְּךָ בֵּית יִשְׂרָאֵל, לְחַיִּים טוֹבִים וּלְשָׁלוֹם.","cond":["musaf","ayt"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הַמְבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם.","cond":["musaf"]},{"kind":"text","text":"יִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:\nאֱלֹהַי, נְצֹר לְשׁוֹנִי מֵרָע וּשְׂפָתַי מִדַּבֵּר מִרְמָה, וְלִמְקַלְלַי נַפְשִׁי תִדֹּם, וְנַפְשִׁי כֶּעָפָר לַכֹּל תִּהְיֶה. פְּתַח לִבִּי בְּתוֹרָתֶךָ, וּבְמִצְוׂתֶיךָ תִּרְדֹף נַפְשִׁי. וְכָל הַחוֹשְׁבִים עָלַי רָעָה, מְהֵרָה הָפֵר עֲצָתָם וְקַלְקֵל מַחֲשַׁבְתָּם. עֲשֵׂה לְמַעַן שְׁמֶךָ, עֲשֵׂה לְמַעַן יְמִינֶךָ, עֲשֵׂה לְמַעַן קְדֻשָּׁתֶךָ, עֲשֵׂה לְמַעַן תּוֹרָתֶךָ. לְמַעַן יֵחָלְצוּן יְדִידֶיךָ הוֹשִׁיעָה יְמִינְךָ וַעֲנֵנִי:\nיִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:","cond":["musaf"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["musaf","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["musaf","ayt"]},{"kind":"text","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁיִּבָּנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵינוּ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתֶךָ, וְשָׁם נַעֲבָדְךָ בְּיִרְאָה כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמוֹנִיּוֹת. וְעָרְבָה לַיהוה מִנְחַת יְהוּדָה וִירוּשָׁלָיִם כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמֹנִיּוֹת:","cond":["musaf"]},{"kind":"header","text":"חזרת הש\"ץ","cond":["musaf"]},{"kind":"instruction","text":"חזרת הש\"ץ","cond":["musaf"]},{"kind":"text","text":"כִּי שֵׁם יהוה אֶקְרָא, הָבוּ גֹדֶל לֵאלֹהֵינוּ:\nאֲדֹנָי, שְׂפָתַי תִּפְתָּח, וּפִי יַגִּיד תְּהִלָּתֶךָ:","cond":["musaf"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק, וֵאלֹהֵי יַעֲקֹב, הָאֵל הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, וְקוֹנֵה הַכֹּל, וְזוֹכֵר חַסְדֵי אָבוֹת, וּמֵבִיא גוֹאֵל לִבְנֵי בְנֵיהֶם לְמַעַן שְׁמוֹ בְּאַהֲבָה.","cond":["musaf"]},{"kind":"special","text":"זָכְרֵנוּ לְחַיִּים, מֶלֶךְ חָפֵץ בַּחַיִּים, וְכָתְבֵנוּ בְּסֵפֶר הַחַיִּים, לְמַעַנְךָ אֱלֹהִים חַיִּים.","cond":["musaf","ayt"]},{"kind":"text","text":"מֶלֶךְ עוֹזֵר וּמוֹשִׁיעַ וּמָגֵן. בָּרוּךְ אַתָּה יהוה, מָגֵן אַבְרָהָם.","cond":["musaf"]},{"kind":"text","text":"אַתָּה גִּבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֵּה מֵתִים אַתָּה רַב לְהוֹשִׁיעַ,","cond":["musaf"]},{"kind":"summer","text":"מוֹרִיד הַטָּל,","cond":["musaf","summerTal"]},{"kind":"winter","text":"מַשִּׁיב הָרוּחַ וּמוֹרִיד הַגֶּשֶׁם,","cond":["musaf","winterTal"]},{"kind":"text","text":"מְכַלְכֵּל חַיִּים בְּחֶסֶד, מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים, סוֹמֵךְ נוֹפְלִים, וְרוֹפֵא חוֹלִים וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמוּנָתוֹ לִישֵׁנֵי עָפָר. מִי כָמוֹךָ בַּעַל גְּבוּרוֹת וּמִי דּוֹמֶה לָךְ, מֶלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִיחַ יְשׁוּעָה.","cond":["musaf"]},{"kind":"special","text":"מִי כָמוֹךָ אַב הָרַחֲמִים, זוֹכֵר יְצוּרָיו לְחַיִּים בְּרַחֲמִים.","cond":["musaf","ayt"]},{"kind":"text","text":"וְנֶאֱמָן אַתָּה לְהַחֲיוֹת מֵתִים. בָּרוּךְ אַתָּה יהוה, מְחַיֵּה הַמֵּתִים.","cond":["musaf"]},{"kind":"header","text":"קדושה","cond":["musaf","noHoshanaRaba"]},{"kind":"instruction","text":"קדושה בחזרת הש\"ץ:","cond":["musaf","noHoshanaRaba"]},{"kind":"text","text":"נְקַדֵּשׁ אֶת שִׁמְךָ בָּעוֹלָם כְּשֵׁם שֶׁמַּקְדִּישִׁים אוֹתוֹ בִּשְׁמֵי מָרוֹם, כַּכָּתוּב עַל יַד נְבִיאֶךָ:\nוְקָרָא זֶה אֶל זֶה וְאָמַר:\nקו\"ח: קָדוֹשׁ, קָדוֹשׁ, קָדוֹשׁ יהוה צְבָאוֹת, מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ:\nחזן: לְעֻמָּתָם בָּרוּךְ יֹאמֵרוּ:\nקו\"ח: בָּרוּךְ כְּבוֹד יהוה מִמְּקוֹמוֹ:\nחזן: וּבְדִבְרֵי קָדְשְׁךָ כָּתוּב לֵאמֹר:\nקו\"ח: יִמְלֹך יהוה לְעוֹלָם, אֱלֹהַיִך צִיּוֹן לְדֹר וָדֹר, הַלְלוּיָהּ:\n\nלְדוֹר וָדוֹר נַגִּיד גָּדְלֶךָ וּלְנֵצַח נְצָחִים קְדֻשָּׁתְךָ נַקְדִּישׁ, וְשִׁבְחֲךָ אֱלֹהֵינוּ מִפִּינוּ לֹא יָמוּשׁ לְעוֹלָם וָעֵד, כִּי אֵל מֶלֶךְ גָּדוֹל וְקָדוֹשׁ אָתָּה.","cond":["musaf","noHoshanaRaba"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יהוה, הַמֶּלֶךְ הַקָּדוֹשׁ.","cond":["musaf","noHoshanaRaba","ayt"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הָאֵל הַקָּדוֹשׁ.","cond":["musaf","noHoshanaRaba","noayt"]},{"kind":"header","text":"קדושה","cond":["musaf","hoshanaRaba"]},{"kind":"instruction","text":"קדושה בחזרת הש\"ץ:","cond":["musaf","hoshanaRaba"]},{"kind":"text","text":"נַעֲרִיצְךָ וְנַקְדִישְׁךָ כְּסוֹד שִׂיחַ שַׂרְפֵי קֹדֶשׁ, הַמַּקְדִּישִׁים שִׁמְךָ בַּקֹּדֶשׁ, כַּכָּתוּב עַל יַד נְבִיאֶךָ: וְקָרָא זֶה אֶל זֶה וְאָמַר:\nקו\"ח: קָדוֹשׁ, קָדוֹשׁ, קָדוֹשׁ יהוה צְבָאוֹת, מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ:\nחזן: כְּבוֹדוֹ מָלֵא עוֹלָם, מְשָׁרְתָיו שׁוֹאֲלִים זֶה לָזֶה אַיֵּה מְקוֹם כְּבוֹדוֹ. לְעֻמָּתָם בָּרוּךְ יֹאמֵרוּ:\nקו\"ח: בָּרוּךְ כְּבוֹד יהוה מִמְּקוֹמוֹ:\nחזן: מִמְּקוֹמוֹ הוּא יִפֶן בְּרַחֲמִים, וְיָחֹן עַם הַמְיַחֲדִים שְׁמוֹ עֶרֶב וָבֹקֶר בְּכָל יוֹם תָּמִיד, פַּעֲמַיִם בְּאַהֲבָה שְׁמַע אוֹמְרִים:\nקו\"ח: שְׁמַע יִשרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:\nחזן: הוּא אֱלֹהֵינוּ, הוּא אָבִינוּ, הוּא מַלְכֵּנוּ, הוּא מוֹשִׁיעֵנוּ, וְהוּא יַשְׁמִיעֵנוּ בְּרַחֲמָיו שֵׁנִית לְעֵינֵי כָּל חָי, לִהְיוֹת לָכֶם לֵאלֹהִים,\nקו\"ח: אֲנִי יהוה אֱלֹהֵיכֶם:\nקו\"ח: אַדִּיר אַדִּירֵנוּ, יהוה אֲדֹנֵינוּ, מָה אַדִּיר שִׁמְךָ בְּכָל הָאָרֶץ: וְהָיָה יהוה לְמֶלֶךְ עַל כָּל הָאָרֶץ, בַּיּוֹם הַהוּא יִהְיֶה יהוה אֶחָד וּשְמוֹ אֶחָד:\nחזן: וּבְדִבְרֵי קָדְשְׁךָ כָּתוּב לֵאמֹר:\nקו\"ח: יִמְלֹךְ יהוה לְעוֹלָם, אֱלֹהַיִךְ צִיּוֹן לְדֹר וָדֹר, הַלְלוָּיהּ:\n\nלְדוֹר וָדוֹר נָגִיד גָדְלֶךָ וּלְנֵצַח נְצָחִים קְדֻשָּׁתְךָ נַקְדִּישׁ, וְשִׁבְחֲךָ אֱלֹהֵינוּ מִפִּינוּ לֹא יָמוּשׁ לְעוֹלָם וָעֵד, כִּי אֵל מֶלֶךְ גָּדוֹל וְקָדוֹשׁ אָתָּה. בָּרוּךְ אַתָּה יהוה, הָאֵל הַקָּדוֹשׁ.","cond":["musaf","hoshanaRaba"]},{"kind":"text","text":"רָאשֵׁי חֳדָשִׁים לְעַמְּךָ נָתָתָּ, זְמַן כַּפָּרָה לְכָל תּוֹלְדוֹתָם, בִּהְיוֹתָם מַקְרִיבִים לְפָנֶיךָ זִבְחֵי רָצוֹן, וּשְׂעִירֵי חַטָּאת לְכַפֵּר בַּעֲדָם, זִכָּרוֹן לְכֻלָּם יִהְיוּ, וּתְשׁוּעַת נַפְשָׁם מִיַּד שׂוֹנֵא. מִזְבֵּחַ חָדָשׁ בְּצִיּוֹן תָּכִין, וְעוֹלַת רֹאשׁ חֹדֶשׁ נַעֲלֶה עָלָיו, וּשְׂעִירֵי עִזִּים נַעֲשֶׂה בְרָצוֹן, וּבַעֲבוֹדַת בֵּית הַמִּקְדָּשׁ נִשְׂמַח כֻּלָּנוּ, וּבְשִׁירֵי דָּוִד עַבְדְּךָ הַנִּשְׁמָעִים בְּעִירֶךָ, הָאֲמוּרִים לִפְנֵי מִזְבְּחֶךָ, אַהֲבַת עוֹלָם תָּבִיא לָהֶם וּבְרִית אָבוֹת לַבָּנִים תִּזְכּוֹר. וַהֲבִיאֵנוּ לְצִיּוֹן עִירְךָ בְּרִנָּה, וְלִירוּשָׁלַיִם בֵּית מִקְדָּשְׁךָ בְּשִׂמְחַת עוֹלָם, וְשָׁם נַעֲשֶׂה לְפָנֶיךָ אֶת קָרְבְּנוֹת חוֹבוֹתֵינוּ, תְּמִידִים כְּסִדְרָם וּמוּסָפִים כְּהִלְכָתָם, וְאֶת מוּסַף יוֹם רֹאשׁ הַחֹדֶשׁ הַזֶּה נַעֲשֶׂה וְנַקְרִיב לְפָנֶיךָ בְּאַהֲבָה כְּמִצְוַת רְצוֹנֶךָ, כְּמוֹ שֶׁכָּתַבְתָּ עָלֵינוּ בְּתוֹרָתֶךָ עַל יְדֵי מֹשֶׁה עַבְדֶּךָ מִפִּי כְבוֹדֶךָ, כָּאָמוּר: וּבְרָאשֵׁי חָדְשֵׁיכֶם תַּקְרִיבוּ עוֹלָה לַיהוה, פָּרִים בְּנֵי בָקָר שְׁנַיִם וְאַיִל אֶחָד, כְּבָשִׂים בְּנֵי שָׁנָה שִׁבְעָה, תְּמִימִם: וּמִנְחָתָם וְנִסְכֵּיהֶם כִּמְדֻבָּר: שְׁלשָׁה עֶשְׂרֹנִים לַפָּר, וּשְׁנֵי עֶשְׂרֹנִים לָאָיִל, וְעִשָּׂרוֹן לַכֶּבֶשׂ, וְיַיִן כְּנִסְכּוֹ, וְשָׂעִיר לְכַפֵּר, וּשְׁנֵי תְמִידִים כְּהִלְכָתָם.\n\nאֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, חַדֵּשׁ עָלֵינוּ אֶת הַחֹדֶשׁ הַזֶּה לְטוֹבָה וְלִבְרָכָה, לְשָׂשׂוֹן וּלְשִׂמְחָה, לִישׁוּעָה וּלְנֶחָמָה, לְפַרְנָסָה וּלְכַלְכָּלָה, לְחַיִּים וּלְשָׁלוֹם, לִמְחִילַת חֵטְא וְלִסְלִיחַת עָווֹן.","cond":["musaf","rh"]},{"kind":"text","text":"וּלְכַפָּרַת פָּשַׁע.","cond":["musaf","rh","kaparatPasha"]},{"kind":"text","text":"כִּי בְעַמְּךָ יִשְׂרָאֵל בָּחַרְתָּ מִכָּל הָאֻמּוֹת, וְחֻקֵּי רָאשֵׁי חֳדָשִׁים לָהֶם קָבָעְתָּ. בָּרוּךְ אַתָּה יהוה, מְקַדֵּשׁ יִשְׂרָאֵל וְרָאשֵׁי חֳדָשִׁים.","cond":["musaf","rh"]},{"kind":"text","text":"אַתָּה בְחַרְתָּנוּ מִכָּל הָעַמִּים, אָהַבְתָּ אוֹתָנוּ וְרָצִיתָ בָּנוּ, וְרוֹמַמְתָּנוּ מִכָּל הַלְּשׁוֹנוֹת וְקִדַּשְׁתָּנוּ בְּמִצְוׂתֶיךָ, וְקֵרַבְתָּנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶךָ, וְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ עָלֵינוּ קָרָאתָ. וַתִּתֶּן לָנוּ יהוה אֱלֹהֵינוּ בְּאַהֲבָה מוֹעֲדִים לְשִׂמְחָה, חַגִּים וּזְמַנִּים לְשָׂשׂוֹן אֶת יוֹם","cond":["musaf","pesach"]},{"kind":"text","text":"חַג הַמַּצּוֹת הַזֶּה, זְמַן חֵרוּתֵנוּ","cond":["musaf","pesach","pesach"]},{"kind":"text","text":"חַג הַסֻּכּוֹת הַזֶּה, זְמַן שִׂמְחָתֵנוּ","cond":["musaf","pesach","sucot"]},{"kind":"text","text":"מִקְרָא קֹדֶשׁ, זֵכֶר לִיצִיאַת מִצְרָיִם.\n\nוּמִפְּנֵי חֲטָאֵינוּ גָּלִינוּ מֵאַרְצֵנוּ, וְנִתְרַחַקְנוּ מֵעַל אַדְמָתֵנוּ, וְאֵין אֲנַחְנוּ יְכוֹלִים לַעֲלוֹת וְלֵרָאוֹת וּלְהִשְׁתַּחֲווֹת לְפָנֶיךָ, וְלַעֲשׂוֹת חוֹבוֹתֵינוּ בְּבֵית בְּחִירָתֶךָ, בַּבַּיִת הַגָּדוֹל וְהַקָּדוֹשׁ שֶׁנִּקְרָא שִׁמְךָ עָלָיו, מִפְּנֵי הַיָּד שֶׁנִּשְׁתַּלְּחָה בְּמִקְדָּשֶׁךָ. יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן, שֶׁתָּשׁוּב וּתְרַחֵם עָלֵינוּ וְעַל מִקְדָּשְׁךָ בְּרַחֲמֶיךָ הָרַבִּים, וְתִבְנֵהוּ מְהֵרָה וּתְגַדֵּל כְּבוֹדוֹ. אָבִינוּ מַלְכֵּנוּ, גַּלֵּה כְּבוֹד מַלְכוּתְךָ עָלֵינוּ מְהֵרָה, וְהוֹפַע וְהִנָּשֵׂא עָלֵינוּ לְעֵינֵי כָּל חָי, וְקָרֵב פְּזוּרֵינוּ מִבֵּין הַגּוֹיִם, וּנְפוּצוֹתֵינוּ כַּנֵּס מִיַּרְכְּתֵי אָרֶץ. וַהֲבִיאֵנוּ לְצִיּוֹן עִירְךָ בְּרִנָּה, וְלִירוּשָׁלַיִם בֵּית מִקְדָּשְׁךָ בְּשִׂמְחַת עוֹלָם, וְשָׁם נַעֲשֶׂה לְפָנֶיךָ אֶת קָרְבְּנוֹת חוֹבוֹתֵינוּ תְּמִידִים כְּסִדְרָם וּמוּסָפִים כְּהִלְכָתָם, וְאֶת מוּסַף יוֹם","cond":["musaf","pesach"]},{"kind":"text","text":"חַג הַמַּצּוֹת הַזֶּה","cond":["musaf","pesach","pesach"]},{"kind":"text","text":"חַג הַסֻּכּוֹת הַזֶּה","cond":["musaf","pesach","sucot"]},{"kind":"text","text":"נַעֲשֶׂה וְנַקְרִיב לְפָנֶיךָ בְּאַהֲבָה כְּמִצְוַת רְצוֹנֶךָ, כְּמוֹ שֶׁכָּתַבְתָּ עָלֵינוּ בְּתוֹרָתֶךָ עַל יְדֵי מֹשֶׁה עַבְדֶּךָ מִפִּי כְבוֹדֶךָ, כָּאָמוּר:","cond":["musaf","pesach"]},{"kind":"text","text":"וְהִקְרַבְתֶּם אִשֶּׁה עֹלָה לַיהוה, פָּרִים בְּנֵי בָקָר שְׁנַיִם, וְאַיִל אֶחָד, וְשִׁבְעָה כְבָשִׂים בְּנֵי שָׁנָה, תְּמִימִם יִהְיוּ לָכֶם:\nוּמִנְחָתָם וְנִסְכֵּיהֶם כִּמְדֻבָּר: שְׁלֹשָׁה עֶשְׂרֹנִים לַפָּר, וּשְׁנֵי עֶשְׂרֹנִים לָאָיִל, וְעִשָּׂרוֹן לַכֶּבֶשׂ, וְיַיִן כְּנִסְכּוֹ, וְשָׂעִיר לְכַפֵּר, וּשְׁנֵי תְמִידִים כְּהִלְכָתָם.","cond":["musaf","pesach","pesach"]},{"kind":"text","text":":-:-","cond":["musaf","pesach","sucot"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן רַחֵם עָלֵינוּ, טוֹב וּמֵטִיב הִדָּרֶשׁ לָנוּ, שׁוּבָה אֵלֵינוּ בַּהֲמוֹן רַחֲמֶיךָ, בִּגְלַל אָבוֹת שֶׁעָשׂוּ רְצוֹנֶךָ. בְּנֵה בֵיתְךָ כְּבַתְּחִלָּה, וְכוֹנֵן מִקְדָּשְׁךָ עַל מְכוֹנוֹ, וְהַרְאֵנוּ בְּבִנְיָנוֹ וְשַׂמְּחֵנוּ בְּתִקּוּנוֹ, וְהָשֵׁב כֹּהֲנִים לַעֲבוֹדָתָם וּלְוִיִּם לְשִׁירָם וּלְזִמְרָם, וְהָשֵׁב יִשְׂרָאֵל לִנְוֵיהֶם. וְשָׁם נַעֲלֶה וְנֵרָאֶה וְנִשְׁתַּחֲוֶה לְפָנֶיךָ בְּשָׁלֹשׁ פַּעֲמֵי רְגָלֵינוּ כַּכָּתוּב בְּתוֹרָתֶךָ: שָׁלֹשׁ פְּעָמִים בַּשָּׁנָה יֵרָאֶה כָל זְכוּרְךָ אֶת פְּנֵי יהוה אֱלֹהֶיךָ בַּמָּקום אֲשֶׁר יִבְחָר, בְּחַג הַמַּצּוֹת, וּבְחַג הַשָּׁבֻעוֹת, וּבְחַג הַסֻּכּוֹת, וְלא יֵרָאֶה אֶת פְּנֵי יהוה רֵיקָם: אִישׁ כְּמַתְּנַת יָדוֹ, כְּבִרְכַּת יהוה אֱלֹהֶיךָ אֲשֶׁר נָתַן לָךְ:\n\nוְהַשִּׂיאֵנוּ יהוה אֱלֹהֵינוּ אֶת בִּרְכַּת מוֹעֲדֶיךָ, לְחַיִּים וּלְשָׁלוֹם, לְשִׂמְחָה וּלְשָׂשׂוֹן, כַּאֲשֶׁר רָצִיתָ וְאָמַרְתָּ לְבָרְכֵנוּ. קַדְּשֵׁנוּ בְּמִצְוׂתֶיךָ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתֶךָ, שַׂבְּעֵנוּ מִטּוּבֶךָ, וְשַׂמְּחֵנוּ בִּישׁוּעָתֶךָ, וְטַהֵר לִבֵּנוּ לְעָבְדְּךָ בֶּאֱמֶת, וְהַנְחִילֵנוּ יהוה אֱלֹהֵינוּ בְּשִׂמְחָה וּבְשָׂשׂוֹן מוֹעֲדֵי קָדְשֶׁךָ, וְיִשְׂמְחוּ בְךָ יִשְׂרָאֵל מְקַדְּשֵׁי שְׁמֶךָ. בָּרוּךְ אַתָּה יהוה, מְקַדֵּשׁ יִשְׂרָאֵל וְהַזְּמַנִּים.","cond":["musaf","pesach"]},{"kind":"text","text":"אַתָּה בְחַרְתָּנוּ מִכָּל הָעַמִּים, אָהַבְתָּ אוֹתָנוּ וְרָצִיתָ בָּנוּ, וְרוֹמַמְתָּנוּ מִכָּל הַלְּשׁוֹנוֹת וְקִדַּשְׁתָּנוּ בְּמִצְוׂתֶיךָ, וְקֵרַבְתָּנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶךָ, וְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ עָלֵינוּ קָרָאתָ. וַתִּתֶּן לָנוּ יהוה אֱלֹהֵינוּ בְּאַהֲבָה מוֹעֲדִים לְשִׂמְחָה, חַגִּים וּזְמַנִּים לְשָׂשׂוֹן אֶת יוֹם","cond":["musaf","sucot"]},{"kind":"text","text":"חַג הַמַּצּוֹת הַזֶּה, זְמַן חֵרוּתֵנוּ","cond":["musaf","sucot","pesach"]},{"kind":"text","text":"חַג הַסֻּכּוֹת הַזֶּה, זְמַן שִׂמְחָתֵנוּ","cond":["musaf","sucot","sucot"]},{"kind":"text","text":"מִקְרָא קֹדֶשׁ, זֵכֶר לִיצִיאַת מִצְרָיִם.\n\nוּמִפְּנֵי חֲטָאֵינוּ גָּלִינוּ מֵאַרְצֵנוּ, וְנִתְרַחַקְנוּ מֵעַל אַדְמָתֵנוּ, וְאֵין אֲנַחְנוּ יְכוֹלִים לַעֲלוֹת וְלֵרָאוֹת וּלְהִשְׁתַּחֲווֹת לְפָנֶיךָ, וְלַעֲשׂוֹת חוֹבוֹתֵינוּ בְּבֵית בְּחִירָתֶךָ, בַּבַּיִת הַגָּדוֹל וְהַקָּדוֹשׁ שֶׁנִּקְרָא שִׁמְךָ עָלָיו, מִפְּנֵי הַיָּד שֶׁנִּשְׁתַּלְּחָה בְּמִקְדָּשֶׁךָ. יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן, שֶׁתָּשׁוּב וּתְרַחֵם עָלֵינוּ וְעַל מִקְדָּשְׁךָ בְּרַחֲמֶיךָ הָרַבִּים, וְתִבְנֵהוּ מְהֵרָה וּתְגַדֵּל כְּבוֹדוֹ. אָבִינוּ מַלְכֵּנוּ, גַּלֵּה כְּבוֹד מַלְכוּתְךָ עָלֵינוּ מְהֵרָה, וְהוֹפַע וְהִנָּשֵׂא עָלֵינוּ לְעֵינֵי כָּל חָי, וְקָרֵב פְּזוּרֵינוּ מִבֵּין הַגּוֹיִם, וּנְפוּצוֹתֵינוּ כַּנֵּס מִיַּרְכְּתֵי אָרֶץ. וַהֲבִיאֵנוּ לְצִיּוֹן עִירְךָ בְּרִנָּה, וְלִירוּשָׁלַיִם בֵּית מִקְדָּשְׁךָ בְּשִׂמְחַת עוֹלָם, וְשָׁם נַעֲשֶׂה לְפָנֶיךָ אֶת קָרְבְּנוֹת חוֹבוֹתֵינוּ תְּמִידִים כְּסִדְרָם וּמוּסָפִים כְּהִלְכָתָם, וְאֶת מוּסַף יוֹם","cond":["musaf","sucot"]},{"kind":"text","text":"חַג הַמַּצּוֹת הַזֶּה","cond":["musaf","sucot","pesach"]},{"kind":"text","text":"חַג הַסֻּכּוֹת הַזֶּה","cond":["musaf","sucot","sucot"]},{"kind":"text","text":"נַעֲשֶׂה וְנַקְרִיב לְפָנֶיךָ בְּאַהֲבָה כְּמִצְוַת רְצוֹנֶךָ, כְּמוֹ שֶׁכָּתַבְתָּ עָלֵינוּ בְּתוֹרָתֶךָ עַל יְדֵי מֹשֶׁה עַבְדֶּךָ מִפִּי כְבוֹדֶךָ, כָּאָמוּר:","cond":["musaf","sucot"]},{"kind":"text","text":"וְהִקְרַבְתֶּם אִשֶּׁה עֹלָה לַיהוה, פָּרִים בְּנֵי בָקָר שְׁנַיִם, וְאַיִל אֶחָד, וְשִׁבְעָה כְבָשִׂים בְּנֵי שָׁנָה, תְּמִימִם יִהְיוּ לָכֶם:\nוּמִנְחָתָם וְנִסְכֵּיהֶם כִּמְדֻבָּר: שְׁלֹשָׁה עֶשְׂרֹנִים לַפָּר, וּשְׁנֵי עֶשְׂרֹנִים לָאָיִל, וְעִשָּׂרוֹן לַכֶּבֶשׂ, וְיַיִן כְּנִסְכּוֹ, וְשָׂעִיר לְכַפֵּר, וּשְׁנֵי תְמִידִים כְּהִלְכָתָם.","cond":["musaf","sucot","pesach"]},{"kind":"text","text":":-:-","cond":["musaf","sucot","sucot"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן רַחֵם עָלֵינוּ, טוֹב וּמֵטִיב הִדָּרֶשׁ לָנוּ, שׁוּבָה אֵלֵינוּ בַּהֲמוֹן רַחֲמֶיךָ, בִּגְלַל אָבוֹת שֶׁעָשׂוּ רְצוֹנֶךָ. בְּנֵה בֵיתְךָ כְּבַתְּחִלָּה, וְכוֹנֵן מִקְדָּשְׁךָ עַל מְכוֹנוֹ, וְהַרְאֵנוּ בְּבִנְיָנוֹ וְשַׂמְּחֵנוּ בְּתִקּוּנוֹ, וְהָשֵׁב כֹּהֲנִים לַעֲבוֹדָתָם וּלְוִיִּם לְשִׁירָם וּלְזִמְרָם, וְהָשֵׁב יִשְׂרָאֵל לִנְוֵיהֶם. וְשָׁם נַעֲלֶה וְנֵרָאֶה וְנִשְׁתַּחֲוֶה לְפָנֶיךָ בְּשָׁלֹשׁ פַּעֲמֵי רְגָלֵינוּ כַּכָּתוּב בְּתוֹרָתֶךָ: שָׁלֹשׁ פְּעָמִים בַּשָּׁנָה יֵרָאֶה כָל זְכוּרְךָ אֶת פְּנֵי יהוה אֱלֹהֶיךָ בַּמָּקום אֲשֶׁר יִבְחָר, בְּחַג הַמַּצּוֹת, וּבְחַג הַשָּׁבֻעוֹת, וּבְחַג הַסֻּכּוֹת, וְלא יֵרָאֶה אֶת פְּנֵי יהוה רֵיקָם: אִישׁ כְּמַתְּנַת יָדוֹ, כְּבִרְכַּת יהוה אֱלֹהֶיךָ אֲשֶׁר נָתַן לָךְ:\n\nוְהַשִּׂיאֵנוּ יהוה אֱלֹהֵינוּ אֶת בִּרְכַּת מוֹעֲדֶיךָ, לְחַיִּים וּלְשָׁלוֹם, לְשִׂמְחָה וּלְשָׂשׂוֹן, כַּאֲשֶׁר רָצִיתָ וְאָמַרְתָּ לְבָרְכֵנוּ. קַדְּשֵׁנוּ בְּמִצְוׂתֶיךָ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתֶךָ, שַׂבְּעֵנוּ מִטּוּבֶךָ, וְשַׂמְּחֵנוּ בִּישׁוּעָתֶךָ, וְטַהֵר לִבֵּנוּ לְעָבְדְּךָ בֶּאֱמֶת, וְהַנְחִילֵנוּ יהוה אֱלֹהֵינוּ בְּשִׂמְחָה וּבְשָׂשׂוֹן מוֹעֲדֵי קָדְשֶׁךָ, וְיִשְׂמְחוּ בְךָ יִשְׂרָאֵל מְקַדְּשֵׁי שְׁמֶךָ. בָּרוּךְ אַתָּה יהוה, מְקַדֵּשׁ יִשְׂרָאֵל וְהַזְּמַנִּים.","cond":["musaf","sucot"]},{"kind":"text","text":"רְצֵה יהוה אֱלֹהֵינוּ בְּעַמְּךָ יִשְׂרָאֵל וּבִתְפִלָּתָם, וְהָשֵׁב אֶת הָעֲבוֹדָה לִדְבִיר בֵּיתֶךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם, בְּאַהֲבָה תְקַבֵּל בְּרָצוֹן. וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּךָ. וְתֶחֱזֶינָה עֵינֵינוּ בְּשׁוּבְךָ לְצִיּוֹן בְּרַחֲמִים. בָּרוּךְ אַתָּה יהוה, הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן.","cond":["musaf"]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שָׁאַתָּה הוּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ לְעוֹלָם וָעֶד. צוּר חַיֵּינוּ, מָגֵן יִשְׁעֵנוּ אַתָּה הוּא לְדוֹר וָדוֹר. נוֹדֶה לְּךָ וּנְסַפֵּר תְּהִלָּתֶךָ עַל חַיֵּינוּ הַמְּסוּרִים בְּיָדֶךָ, וְעַל נִשְׁמוֹתֵינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּיךָ שֶׁבְּכָל יוֹם עִמָּנוּ, וְעַל נִפְלְאוֹתֶיךָ וְטוֹבוֹתֶיךָ שֶׁבְּכָל עֵת, עֶרֶב וָבֹקֶר וְצָהֳרָיִם. הַטּוֹב כִּי לֹא כָלוּ רַחֲמֶיךָ, וְהַמְרַחֵם כִּי לֹא תַמּוּ חֲסָדֶיךָ. מֵעוֹלָם קִוִּינוּ לָךְ.","cond":["musaf"]},{"kind":"header","text":"מודים דרבנן","cond":["musaf"]},{"kind":"instruction","text":"מודים דרבנן:","cond":["musaf"]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שָׁאַתָּה הוּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי כָל בָּשָׂר, יוֹצְרֵנוּ יוֹצֵר בְּרֵאשִׁית. בְּרָכוֹת וְהוֹדָאוֹת לְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ, עַל שֶׁהֶחֱיִיתָנוּ וְקִיַּמְתָּנוּ. כֵּן תְּחַיֵּנוּ וּתְקַיְּמֵנוּ, וְתֶאֱסוֹף גָּלֻיּוֹתֵינוּ לְחַצְרוֹת קָדְשֶׁךָ, לִשְׁמוֹר חֻקֶּיךָ וְלַעֲשׂוֹת רְצוֹנֶךָ, וּלְעָבְדְּךָ בְּלֵבָב שָׁלֵם, עַל שֶׁאֲנַחְנוּ מוֹדִים לָךְ. בָּרוּךְ אֵל הַהוֹדָאוֹת.","cond":["musaf"]},{"kind":"special","text":"עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מַתִּתְיָהוּ בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְהַשְׁכִּיחָם תּוֹרָתֶךָ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנֶךָ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּטְמֵאִים בְּיַד טְהוֹרִים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, וּלְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמֶךָ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כֵּן בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ לְהוֹדוֹת וּלְהַלֵּל לְשִׁמְךָ הַגָּדוֹל.","cond":["musaf","chanuka"]},{"kind":"special","text":"עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים, מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ, וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ, וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְּרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ (, וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה).","cond":["musaf","purim"]},{"kind":"text","text":"וְעַל כֻּלָּם יִתְבָּרַךְ וְיִתְרוֹמַם שִׁמְךָ מַלְכֵּנוּ תָּמִיד לְעוֹלָם וָעֶד.","cond":["musaf"]},{"kind":"special","text":"וּכְתֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶךָ.","cond":["musaf","ayt"]},{"kind":"text","text":"וְכֹל הַחַיִּים יוֹדוּךָ סֶּלָה, וִיהַלְלוּ אֶת שִׁמְךָ בֶּאֱמֶת, הָאֵל יְשׁוּעָתֵנוּ וְעֶזְרָתֵנוּ סֶלָה. בָּרוּך אַתָּה יהוה, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת.","cond":["musaf"]},{"kind":"header","text":"ברכת כהנים","cond":["musaf"]},{"kind":"instruction","text":"ברכת כהנים לחזרת הש\"ץ:\n\nאם לא עלו כהנים לדוכן הש\"ץ אומר או\"א (נמצא בהמשך).\n\nאם עלו שני כהנים לדוכן קוראים להם - כֹּהֲנִים:\n\nהכהנים מברכים:","cond":["musaf"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בִּקְדֻשָּׁתוֹ שֶׁל אַהֲרֹן, וְצִוָּנוּ לְבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בְּאַהֲבָה.\n\nיְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ:\nיָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ:\nיִשָּׂא יהוה פָּנָיו אֵלֶיךָ וְיָשֵׂם לְךָ שָׁלוֹם:","cond":["musaf"]},{"kind":"instruction","text":"הקהל אומר:","cond":["musaf"]},{"kind":"text","text":"אַדִּיר בַּמָּרוֹם שׁוֹכֵן בִּגְבוּרָה, אַתָּה שָׁלוֹם וְשִׁמְךָ שָׁלוֹם. יְהִי רָצוֹן שֶׁתָּשִׂים עָלֵינוּ וְעַל כָּל עַמְּךָ בֵּית יִשְׂרָאֵל חַיִּים וּבְרָכָה לְמִשְׁמֶרֶת שָׁלוֹם.","cond":["musaf"]},{"kind":"instruction","text":"הכהנים אומרים","cond":["musaf"]},{"kind":"text","text":"רִבּוֹנוֹ שֶׁל עוֹלָם, עָשִׂינוּ מַה שֶּׁגָּזַרְתָּ עָלֵינוּ, אַף אַתָּה עֲשֵׂה עִמָּנוּ כְּמוֹ שֶׁהִבְטַחְתָּנוּ: הַשְׁקִיפָה מִמְּעוֹן קָדְשְׁךָ מִן הַשָּׁמַיִם, וּבָרֵךְ אֶת עַמְּךָ אֶת יִשְׂרָאֵל, וְאֵת הָאֲדָמָה אֲשֶׁר נָתַתָּה לָנוּ, כַּאֲשֶׁר נִשְׁבַּעְתָּ לַאֲבֹתֵינוּ, אֶרֶץ זָבַת חָלָב וּדְבָשׁ:","cond":["musaf"]},{"kind":"instruction","text":"אם לא עלו כהנים לדוכן הש\"ץ אומר:","cond":["musaf"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, בָּרְכֵנוּ בַּבְּרָכָה הַמְשֻׁלֶּשֶׁת בַּתּוֹרָה הַכְּתוּבָה עַל יְדֵי מֹשֶׁה עַבְדֶּךָ, הָאֲמוּרָה מִפִּי אַהֲרֹן וּבָנָיו כֹּהֲנִים עַם קְדוֹשֶׁךָ, כָּאָמוּר: יְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ: יָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ: יִשָּׂא יהוה פָּנָיו אֵלֶיךָ וְיָשֵׂם לְךָ שָׁלוֹם:","cond":["musaf"]},{"kind":"text","text":"שִׂים שָׁלוֹם טוֹבָה וּבְרָכָה, חֵן וָחֶסֶד וְרַחֲמִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל עַמֶּךָ, בָּרְכֵנוּ אָבִינוּ כֻּלָּנוּ כְּאֶחָד בְּאוֹר פָּנֶיךָ, כִּי בְאוֹר פָּנֶיךָ נָתַתָּ לָּנוּ יהוה אֱלֹהֵינוּ תּוֹרַת חַיִּים וְאַהֲבַת חֶסֶד, וּצְדָקָה וּבְרָכָה וְרַחֲמִים וְחַיִּים וְשָׁלוֹם, וְטוֹב בְּעֵינֶיךָ לְבָרֵךְ אֶת עַמְּךָ יִשְׂרָאֵל בְּכָל עֵת וּבְכָל שָׁעָה בִּשְׁלוֹמֶךָ.","cond":["musaf"]},{"kind":"special","text":"בְּסֵפֶר חַיִּים, בְּרָכָה וְשָׁלוֹם, וּפַרְנָסָה טוֹבָה, נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ, אֲנַחְנוּ וְכָל עַמְּךָ בֵּית יִשְׂרָאֵל, לְחַיִּים טוֹבִים וּלְשָׁלוֹם.","cond":["musaf","ayt"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הַמְבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם.","cond":["musaf"]},{"kind":"text","text":"יִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:","cond":["musaf"]},{"kind":"header","text":"הושענות","cond":["sucot"]},{"kind":"instruction","text":"הושענות","cond":["sucot"]},{"kind":"instruction","text":"מוציאים את כל ספרי התורה אל הבימה.","cond":["sucot","hoshanaraba"]},{"kind":"instruction","text":"מוציאים ספר תורה אל הבימה.","cond":["sucot","noHoshanaraba"]},{"kind":"instruction","text":"החזן אומר משפט משפט ואחריו הקהל:","cond":["sucot"]},{"kind":"text","text":"הוֹשַׁע נָא לְמַעַנְךָ אֱלֹהֵינוּ, הוֹשַׁע נָא.\nהוֹשַׁע נָא לְמַעַנְךָ בּוֹרְאֵנוּ, הוֹשַׁע נָא.\nהוֹשַׁע נָא לְמַעַנְךָ גּוֹאֲלֵנוּ, הוֹשַׁע נָא.\nהוֹשַׁע נָא לְמַעַנְךָ דּוֹרְשֵׁנוּ, הוֹשַׁע נָא.","cond":["sucot"]},{"kind":"instruction","text":"מתחילים להקיף את הבימה עם ארבעת המינים. אבל ומי שאין לו ארבעה מינים לא יקיף עם הציבור.","cond":["sucot"]},{"kind":"text","text":"=-=-","cond":["sucot"]},{"kind":"instruction","text":"מפסיקים להקיף את הבימה ואומרים:","cond":["sucot"]},{"kind":"text","text":"אֲנִי וָהוֹ הוֹשִׁיעָה נָּא.\n\nכְּהוֹשַׁעְתָּ אֵלִים בְּלוּד עִמָּךְ, בְּצֵאתְךָ לְיֵשַׁע עַמָּךְ, כֵּן הוֹשַׁע נָא.\nכְּהוֹשַׁעְתָּ גּוֹי וֵאלֹהִים, דְרוּשִׁים לְיֵשַׁע אֱלֹהִים, כֵּן הוֹשַׁע נָא.\nכְּהוֹשַׁעְתָּ הֲמוֹן צִבְאוֹת, וְעִמָּם מַלְאֲכֵי צְבָאוֹת, כֵּן הוֹשַׁע נָא.\nכְּהוֹשַׁעְתָּ זַכִּים מִבֵּית עֲבָדִים, חַנּוּן בְּיָדָם מַעֲבִידִים, כֵּן הוֹשַׁע נָא.\nכְּהוֹשַׁעְתָּ טְבוּעִים בְּצוּל גְּזָרִים, יְקָרְךָ עִמָּם מַעֲבִירִים, כֵּן הוֹשַׁע נָא.\nכְּהוֹשַׁעְתָּ כַּנָּה מְשׁוֹרֶרֶת וַיּוֹשַׁע, לְגוֹחָהּ מְצֻיֶּנֶת וַיִּוָּשַׁע, כֵּן הוֹשַׁע נָא.\nכְּהוֹשַׁעְתָּ מַאֲמַר \"וְהוֹצֵאתִי אֶתְכֶם\", נָקוּב \"וְהוּצֵאתִי אִתְּכֶם\", כֵּן הוֹשַׁע נָא.\nכְּהוֹשַׁעְתָּ סוֹבְבֵי מִזְבֵּחַ, עוֹמְסֵי עֲרָבָה לְהַקִּיף מִזְבֵּחַ, כֵּן הוֹשַׁע נָא.\nכְּהוֹשַׁעְתָּ פִּלְאֵי אָרוֹן כְּהֻפְשַׁע, צִעֵר פְּלֶשֶׁת בַּחֲרוֹן אַף וְנוֹשַׁע, כֵּן הוֹשַׁע נָא.\nכְּהוֹשַׁעְתָּ קְהִלּוֹת בָּבֶלָה שָׁלַחְתָּ, רַחוּם לְמַעֲנָם שֻׁלַּחְתָּ, כֵּן הוֹשַׁע נָא.\nכְּהוֹשַׁעְתָּ שְׁבוּת שִׁבְטֵי יַעֲקֹב, תָּשׁוּב וְתָשִׁיב שְׁבוּת אָהֳלֵי יַעֲקֹב וְהוֹשִׁיעָה נָּא.\nכְּהוֹשַׁעְתָּ שׁוֹמְרֵי מִצְוׂת וְחוֹכֵי יְשׁוּעוֹת, אֵל לְמוֹשָׁעוֹת, וְהוֹשִׁיעָה נָּא.\n\nאֲנִי וָהוֹ הוֹשִׁיעָה נָּא.","cond":["sucot"]},{"kind":"text","text":"הוֹשַׁע נָא תִּתְּנֵנוּ לְשֵׁם וְלִתְהִלָּה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּשִׁיבֵנוּ אֶל הַחֶבֶל וְאֶל הַנַּחֲלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּרוֹמְמֵנוּ לְמַעְלָה לְמַעְלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּקַבְּצֵנוּ לְבֵית הַתְּפִלָּה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תַּצִּיבֵנוּ כְּעֵץ עַל פַּלְגֵי מַיִם שְׁתוּלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תִּפְדֵּנוּ מִכָּל נֶגַע וּמַחֲלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּעַטְּרֵנוּ בְּאַהֲבָה כְלוּלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּשַׂמְּחֵנוּ בְּבֵית הַתְּפִלָּה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּנַהֲלֵנוּ עַל מֵי מְנוּחוֹת סֶלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּמַלְאֵנוּ חָכְמָה וְשִׂכְלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תַּלְבִּישֵׁנוּ עֹז וּגְדֻלָּה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תַּכְתִּירֵנוּ בְּכֶתֶר כְּלוּלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּיַשְּׁרֵנוּ בְּאֹרַח סְלוּלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תִּטָּעֵנוּ בְּיֹשֶׁר מְסִלָּה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּחָנֵּנוּ בְּרַחֲמִים וּבְחֶמְלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תַּזְכִּירֵנוּ בְּמִי זֹאת עוֹלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תּוֹשִׁיעֵנוּ לְקֵץ הַגְּאֻלָּה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּהַדְּרֵנוּ בְּזִיו הֲמוּלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תַּדְבִּיקֵנוּ כְּאֵזוֹר חֲתוּלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּגַדְּלֵנוּ בְּיָד הַגְּדוֹלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּבִיאֵנוּ לְבֵיתְךָ בְּרִנָּה וְצָהֳלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּאַדְּרֵנוּ בְּיֶשַׁע וְגִילָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּאַמְּצֵנוּ בְּרֶוַח וְהַצָּלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּלַבְּבֵנוּ בְּבִנְיַן עִירְךָ כְּבַתְּחִלָּה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּעוֹרְרֵנוּ לְצִיּוֹן בְשִׁכְלוּלָהּ, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּזַכֵּנוּ בְּנִבְנְתָה הָעִיר עַל תִּלָּהּ, הוֹשַׁע נָא.\nהוֹשַׁע נָא תַּרְבִּיצֵנוּ בְּשָׂשׂוֹן וְגִילָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּחַזְקֵנוּ אֱלֹהֵי יַעֲקֹב סֶלָה, הוֹשַׁע נָא.","cond":["sucot","hoshanaraba"]},{"kind":"instruction","text":"חזן וקהל:","cond":["sucot","hoshanaraba"]},{"kind":"text","text":"אָנָּא, הוֹשִׁיעָה נָּא.\n\nאָנָּא אֱזֹן חִין תְּאֵבֵי יִשְׁעָךְ, בְּעַרְבֵי נַחַל לְשַׁעְשְׁעָךְ, וְהוֹשִׁיעָה נָּא.\nאָנָּא גְאַל כַּנַּת נִטְעָךְ, דּוּמָה בְּטַאטְאָךְ, וְהוֹשִׁיעָה נָּא.\nאָנָּא הַבֵּט לַבְּרִית טִבְעָךְ, וּמַחֲשַׁכֵּי אֶרֶץ בְּהַטְבִּיעָךְ, וְהוֹשִׁיעָה נָּא.\nאָנָּא זְכָר לָנוּ אָב יִדְּעָךְ, חַסְדְּךָ לָמוֹ בְּהוֹדִיעָךְ, וְהוֹשִׁיעָה נָּא.\nאָנָּא טְהוֹרֵי לֵב בְּהַפְלִיאָךְ, יִוָּדַע כִּי הוּא פִלְאָךְ, וְהוֹשִׁיעָה נָּא.\nאָנָּא כַּבִּיר כֹּחַ תֵּן לָנוּ יִשְׁעָךְ, לַאֲבוֹתֵינוּ כְּהִשָּׁבְעָךְ, וְהוֹשִׁיעָה נָּא.\nאָנָּא מַלֵּא מִשְׁאֲלוֹת עַם מְשַׁוְּעָךְ, נֶעֱקַד בְּהַר מוֹר כְּמוֹ שִׁוְּעָךְ, וְהוֹשִׁיעָה נָּא.\nאָנָּא סַגֵּב אֶשְׁלֵי נִטְעָךְ, עָרִיצִים בַּהֲנִיעָךְ, וְהוֹשִׁיעָה נָּא.\nאָנָּא פְּתַח לָנוּ אוֹצְרוֹת רִבְעָךְ, צִיָּה מֵהֶם בְּהַרְבִּיעָךְ, וְהוֹשִׁיעָה נָּא.\nאָנָּא קוֹרְאֶיךָ אֶרֶץ בְּרוֹעֲעָךְ, רְעֵם בְּטוּב מִרְעָךְ, וְהוֹשִׁיעָה נָּא.\nאָנָּא שְׁעָרֶיךָ תַּעַל מִמְּשׁוֹאָךְ, תֵּל תַּלְפִּיּוֹת בְּהַשִּׁיאָךְ, וְהוֹשִׁיעָה נָּא.","cond":["sucot","hoshanaraba"]},{"kind":"instruction","text":"חזן וקהל:","cond":["sucot","hoshanaraba"]},{"kind":"text","text":"אָנָּא, אֵל נָא, הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא.\n\nאֵל נָּא תָּעִינוּ כְּשֶׂה אוֹבֵד, שְׁמֵנוּ מִסִּפְרְךָ אַל תְּאַבֵּד, הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא.\nאֵל נָּא רְעֵה אֶת צֹאן הַהֲרֵגָה, קְצוּפָה וְעָלֶיךָ הֲרוּגָה, הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא.\nאֵל נָא צֹאנְךָ וְצֹאן מַרְעִיתֶךָ, פְּעוּלָתֶךָ וְרַעְיָתֶךָ, הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא.\nאֵל נָא עֲנִיֵּי הַצֹּאן, שִׂיחָם עֲנֵה בְּעֵת רָצוֹן, הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא.\nאֵל נָא נוֹשְׂאֵי לְךָ עַיִן, מִתְקוֹמְמֶיךָ יִהְיוּ כְאַיִן, הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא.\nאֵל נָא לִמְנַסְּכֵי לְךָ מַיִם, כְּמִמַּעַיְנֵי הַיְּשׁוּעָה יִשְׁאֲבוּן מַיִם, הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא.\nאֵל נָא יַעֲלוּ לְצִיּוֹן מוֹשִׁיעִים, טְפוּלִים בְּךָ וּבְשִׁמְךָ נוֹשָׁעִים, הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא.\nאֵל נָא חֲמוּץ בְּגָדִים, זְעֹם לְנַעֵר כָּל בּוֹגְדִים, הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא.\nאֵל נָא וְזָכוֹר תִּזְכֹּר, הַנְּכוּרֵי בְּלֶתֶךְ וָכוֹר, הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא.\nאֵל נָא דּוֹרְשֶׁיךָ בְּעַנְפֵי עֲרָבוֹת, גַּעְיָם שְׁעֵה מֵעֲרָבוֹת, הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא.\nאֵל נָא בָּרֵךְ בְּעִטּוּר שָׁנָה, אֲמָרַי רְצֵה בְּפִלּוּלִי בְּיוֹם הוֹשַׁעְנָא, הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא.","cond":["sucot","hoshanaraba"]},{"kind":"instruction","text":"חזן וקהל:","cond":["sucot","hoshanaraba"]},{"kind":"text","text":"אָנָּא, אֵל נָא, הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא, אָבִינוּ אָתָּה.\n\nלְמַעַן תָּמִים בְּדוֹרוֹתָיו, הַנִּמְלָט בְּרֹב צִדְקוֹתָיו, מֻצָּל מִשֶּׁטֶף בְּבֹא מַבּוּל מַיִם, לְאוֹם אֲנִי חוֹמָה הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן שָׁלֵם בְּכָל מַעֲשִׂים, הַמְנֻּסָּה בַּעֲשָׂרָה נִסִּים, כְּשָׁר מַלְאָכִים נָם יֻקַּח נָא מְעַט מַיִם, לְבָרָה כַּחַמָּה הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן רַךְ וְיָחִיד נֶחֱנַט פְּרִי לְמֵאָה, זָעַק אַיֵּה הַשֶּׂה לְעוֹלָה, בִּשְׂרוּהוּ עֲבָדָיו מָצָאנוּ מַיִם, לְגוֹלָה וְסוּרָה הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן קִדַּם שְׂאֵת בְּרָכָה, הַנִּשְׂטַם וּלְשִׁמְךָ חִכָּה, מְיַחֵם בְּמַקְלוֹת בְּשִׁקְתוֹת הַמַּיִם, לְדָמְתָה לְתָמָר הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן צָדַק הֱיוֹת לְךָ לְכֹהֵן, כֶּחָתָן פְּאֵר יְכַהֵן, מְנֻסָּה בְּמַסָּה בְּמֵי מְרִיבַת מַיִם, לְהָהָר הַטּוֹב הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן פֹּאַר הֱיוֹת גְּבִיר לְאֶחָיו, יְהוּדָה אֲשֶׁר גָּבַר בְּאֶחָיו, מִסְפַּר רֹבַע מִדָּלְיָו יִזַּל מַיִם, לֹא לָנוּ כִּי אִם לְמַעַנְךָ הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן עָנָו מִכֹּל וְנֶאֱמָן, אֲשֶׁר בְּצִדְקוֹ כִּלְכֵּל הַמָּן, מָשׁוּךְ לְגוֹאֵל וּמָשׁוּי מִמַּיִם, לְזֹאת הַנִּשְׁקָפָה הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן שַׂמְתּוֹ כְּמַלְאֲכֵי מְרוֹמִים, הַלּוֹבֵשׁ אוּרִים וְתוּמִים, מְצֻוָּה לָבֹא בַּמִּקְדָּשׁ בְּקִדּוּשׁ יָדַיִם וְרַגְלַיִם וּרְחִיצַת מַיִם, לְחוֹלַת אַהֲבָה הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן נְבִיאָה מְחוֹלַת מַחֲנַיִם, לִכְמֵהֵי לֵב הוּשְׂמָה עֵינַיִם, לְרַגְלָהּ רָצָה עֲלוֹת וָרֶדֶת בְּאֵר מַיִם, לְטוֹבוּ אֹהָלָיו הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן מְשָׁרֵת לֹא מָשׁ מֵאֹהֶל, וְרוּחַ הַקֹּדֶשׁ עָלָיו אִהֵל, בְּעָבְרוֹ בַיַרְדֵּן נִכְרְתוּ הַמַּיִם, לְיָפָה וּבָרָה הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן לִמַּד רְאוֹת לְטוֹבָה אוֹת, זָעַק אַיֵה נִפְלָאוֹת, מִצָּה טַל מִגִּזָּה מְלֹא הַסֵּפֶל מַיִם, לְכַלַּת לְבָנוֹן הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן כְּלוּלֵי עֲשׂוֹת מִלְחַמְתֶּךָ, אֲשֶׁר בְּיָדָם תַּתָּה יְשׁוּעָתֶךָ, צְרוּפֵי מִגּוֹי בְּלָקְקָם בְּיָדָם מַיִם, לְלֹא בָּגְדוּ בָךְ הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן יָחִיד צוֹרְרִים דָּשׁ, אֲשֶׁר מֵרֶחֶם לְנָזִיר הֻקְדָּשׁ, מִמַּכְתֵּשׁ לֶחִי הִבְקַעְתָּ לוֹ מַיִם, לְמַעַן שֵׁם קָדְשְׁךָ הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן טוֹב הוֹלֵךְ וְגָדֵל, אֲשֶׁר מֵעֹשֶׁק עֵדָה חִדֵּל, בְּשׁוּב עָם מֵחֵטְא צָו שְׁאָב מַיִם, לְנָאוָה כִּירוּשָׁלָיִם הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן חֵיךְ מְכַרְכֵּר בְּשִׁיר, הַמְלַמֵּד תּוֹרָה בְּכָל כְּלֵי שִׁיר, מְנַסֵּךְ לְפָנָיו כְּתָאַב שְׁתוֹת מַיִם, לְשָׂמוּ בְךָ סִבְרָם הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן זָךְ עָלָה בִּסְעָרָה, הַמְקַנֵּא וּמֵשִׁיב עֶבְרָה, לְפִלּוּלוֹ יָרְדָה אֵשׁ וְלִחֲכָה עָפָר וּמַיִם, לְעֵינֶיהָ בְּרֵכוֹת הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן וְשֵׁרֵת בֶּאֱמֶת לְרַבּוֹ, פִּי שְׁנַיִם בְּרוּחוֹ נֶאֱצַל בּוֹ, בְּקַחְתּוֹ מְנַגֵּן נִתְמַלְּאוּ גֵבִים מַיִם, לְפוֹצְחֵי מִי כָמוֹךָ הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן הִרְהֵר עֲשׂוֹת רְצוֹנֶךָ, הַמַּכְרִיז תְּשׁוּבָה לְצֹאנֶךָ, אָז בְּבֹא מְחָרֵף סָתַם עֵינוֹת מַיִם, לְצִיּוֹן מִכְלַל יוֹפִי הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן דְּרָשׁוּךָ בְּתוֹךְ הַגּוֹלָה, וְסוֹדְךָ לָמוֹ נִגְלָה, בְּלִי לְהִתְגָּאֵל דָּרְשׁוּ זֵרְעוֹנִים וּמַיִם, לְקוֹרְאֶיךָ בַּצָּר הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן גָּמַר חָכְמָה וּבִינָה, סוֹפֵר מָהִיר מְפַלֵּשׁ אֲמָנָה, מְחַכְּמֵנוּ אֲמָרִים הַמְשׁוּלִים בְּרַחֲבֵי מַיִם, לְרַבָּתִי עָם הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן בָּאֵי לְךָ הַיּוֹם בְּכָל לֵב, שׁוֹפְכִים לְךָ שִׂיחַ בְּלֹא לֵב וָלֵב, שׁוֹאֲלִים מִמְּךָ עֹז מִטְרוֹת מַיִם, לְשׁוֹרְרוּךָ בַּיָם הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן אוֹמְרֵי יִגְדַּל שְׁמֶךָ, וְהֵם נַחֲלָתְךָ וְעַמֶּךָ, צְמֵאִים לְיֶשְׁעֲךָ כְּאֶרֶץ עֲיֵפָה לְמַיִם, לְתַרְתָּ לָמוֹ מְנוּחָה הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.","cond":["sucot","hoshanaraba"]},{"kind":"instruction","text":"חזן וקהל:","cond":["sucot","hoshanaraba"]},{"kind":"text","text":"הוֹשַׁע נָא, אֵל נָא, אָנָּא הוֹשִׁיעָה נָּא.\nהוֹשַׁע נָא, סְלַח נָּא, וְהַצְלִיחָה נָא, וְהוֹשִׁיעֵנוּ אֵל מָעֻזֵנוּ.","cond":["sucot","hoshanaraba"]},{"kind":"instruction","text":"מניח הלולב מידו ולוקח את ערבות ההושענא ותופסן עד החבטה.","cond":["sucot","hoshanaraba"]},{"kind":"text","text":"תַּעֲנֶה אֱמוּנִים שׁוֹפְכִים לְךָ לֵב כַּמַּיִם, וְהוֹשִׁיעָה נָּא.\nלְמַעַן בָּא בָאֵשׁ וּבַמַּיִם, וְהַצְלִיחָה נָּא\nגָּזַר וְנָם יֻקַּח נָא מְעַט מַיִם, וְהוֹשִׁיעֵנוּ אֵל מָעֻזֵּנוּ.\n\nתַּעֲנֶה דְגָלִים גָּזוּ גִזְרֵי מַיִם, וְהוֹשִׁיעָה נָּא.\nלְמַעַן הַנֶּעֱקַד בְּשַׁעַר הַשָּׁמַיִם, וְהַצְלִיחָה נָּא\nוְשָׁב וְחָפַר בְּאֵרוֹת מַיִם, וְהוֹשִׁיעֵנוּ אֵל מָעֻזֵּנוּ.\n\nתַּעֲנֶה זַכִּים חוֹנִים עֲלֵי מַיִם, וְהוֹשִׁיעָה נָּא.\nלְמַעַן חָלָק מְפַצֵּל מַקְלוֹת בְּשִׁקְתוֹת הַמַּיִם, וְהַצְלִיחָה נָּא.\nטָעַן וְגָל אֶבֶן מִבְּאֵר מַיִם, וְהוֹשִׁיעֵנוּ אֵל מָעֻזֵּנוּ.\n\nתַּעֲנֶה יְדִידִים נוֹחֲלֵי דָת מְשׁוּלַת מַיִם, וְהוֹשִׁיעָה נָּא.\nלְמַעַן כָּרוּ בְּמִשְׁעֲנוֹתָם מַיִם, וְהַצְלִיחָה נָּא.\nלְהָכִין לָמוֹ וּלְצֶאֱצָאֵימוֹ מַיִם, וְהוֹשִׁיעֵנוּ אֵל מָעֻזֵּנוּ.\n\nתַּעֲנֶה מִתְחַנְּנִים כְּבִישִׁימוֹן עֲלֵי מַיִם, וְהוֹשִׁיעָה נָּא.\nלְמַעַן נֶאֱמַן בַּיִת מַסְפִּיק לָעָם מַיִם, וְהַצְלִיחָה נָּא.\nסֶלַע הָךְ וַיָּזוּבוּ מַיִם, וְהוֹשִׁיעֵנוּ אֵל מָעֻזֵּנוּ.\n\nתַּעֲנֶה עוֹנִים עֲלִי בְאֵר מַיִם, וְהוֹשִׁיעָה נָּא.\nלְמַעַן פֻּקַּד בְּמֵי מְרִיבַת מַיִם, וְהַצְלִיחָה נָּא.\nצְמֵאִים לְהַשְׁקוֹתָם מַיִם, וְהוֹשִׁיעֵנוּ אֵל מָעֻזֵּנוּ.\n\nתַּעֲנֶה קְדוֹשִׁים מְנַסְּכִים לְךָ מַיִם, וְהוֹשִׁיעָה נָּא.\nלְמַעַן רֹאשׁ מְשׁוֹרְרִים כְּתָאַב שְׁתוֹת מַיִם, וְהַצְלִיחָה נָּא.\nחָלִילָה פָּץ וְנָסַךְ לְךָ מַיִם, וְהוֹשִׁיעֵנוּ אֵל מָעֻזֵּנוּ.\n\nתַּעֲנֶה שׁוֹאֲלִים בְּרִבּוּעַ אֶשְׁלֵי מַיִם, וְהוֹשִׁיעָה נָּא.\nלְמַעַן תֵּל תַּלְפִּיּוֹת מוֹצָא מַיִם, וְהַצְלִיחָה נָּא.\nתִּפְתַּח אֶרֶץ וְתַרְעִיף שָׁמַיִם, וְהוֹשִׁיעֵנוּ אֵל מָעֻזֵּנוּ.","cond":["sucot","hoshanaraba"]},{"kind":"instruction","text":"חזן וקהל:","cond":["sucot","hoshanaraba"]},{"kind":"text","text":"רַחֶם נָא קְהַל עֲדַת יְשֻׁרוּן, סְלַח וּמְחַל עֲוׂנָם, וְהוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ.\n\nאָז כְּעֵינֵי עֲבָדִים אֶל יַד אֲדוֹנִים, בָּאנוּ לְפָנֶיךָ נִדּוֹנִים, וְהוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ.\nגֵּאֶה אֲדוֹנֵי הָאֲדוֹנִים, נִתְגָּרוּ בָנוּ מְדָנִים, דָּשׁוּנוּ וּבְעָלוּנוּ זוּלָתְךָ אֲדוֹנִים, וְהוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ.\nהֵן גַּשְׁנוּ הַיּוֹם בְּתַחֲנוּן, עָדֶיךָ רַחוּם וְחַנוּן, וְסִפַּרְנוּ נִפְלְאוֹתֶיךָ בְּשִׁנּוּן, וְהוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ.\nזָבַת חָלָב וּדְבָשׁ, נָא אַל תִּיבָשׁ, חַשְׁרַת מַיִם כְּאֵבָיהָ תֶּחְבָּשׁ, וְהוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ.\nטְעֵנוּ בִשְׁמֵנָה, בְּיַד שִׁבְעָה וּשְׁמוֹנָה, יָשָׁר צַדִּיק אֵל אֱמוּנָה, וְהוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ.\nכָּרַתָּ בְרִית לָאָרֶץ, עוֹד כָּל יְמֵי הָאָרֶץ, לְבִלְתִּי פְרָץ בָּהּ פָּרֶץ, וְהוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ.\nמִתְחַנְּנִים עֲלֵי מַיִם, כַּעֲרָבִים עַל יִבְלֵי מַיִם, נָא זְכוֹר לָנוּ נִסּוּךְ הַמַּיִם, וְהוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ.\nשִׂיחִים בְּדֶרֶךְ מַטָּעָתָם, עוֹמְסִים בְּשַׁוְעָתָם, עֲנֵם בְּקוֹל פְּגִיעָתָם, וְהוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ.\nפּוֹעֵל יְשׁוּעוֹת, פְּנֵה לְפִלּוּלָם שְׁעוֹת, צַדְּקֵם אֵל לְמוֹשָׁעוֹת, וְהוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ.\nקוֹל רִגְשָׁם תִּשַׁע, תִּפְתַּח אֶרֶץ וְיִפְרוּ יֶשַׁע, רַב לְהוֹשִׁיעַ וְלֹא חָפֵץ רֶשַׁע, וְהוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ.","cond":["sucot","hoshanaraba"]},{"kind":"instruction","text":"חזן וקהל:","cond":["sucot","hoshanaraba"]},{"kind":"text","text":"שַׁעֲרֵי שָׁמַיִם פְּתַח, וְאוֹצָרְךָ הַטּוֹב לָנוּ תִפְתַּח, תּוֹשִׁיעֵנוּ וְרִיב אַל תִּמְתַּח, וְהוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ.","cond":["sucot","hoshanaraba"]},{"kind":"instruction","text":"חזן וקהל:","cond":["sucot","hoshanaraba"]},{"kind":"text","text":"קוֹל מְבַשֵּׂר מְבַשֵּׂר וְאוֹמֵר.\n\nאֹמֶץ יֶשְׁעֲךָ בָּא, קוֹל דּוֹדִי הִנֵּה זֶה בָּא, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל בָּא בְּרִבְבוֹת כִּתִּים, לַעֲמֹד עַל הַר הַזֵּיתִים, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל גִּשְׁתּוֹ בַּשּׁוֹפָר לִתְקַע, תַּחְתָּיו הַר יִבָּקַע, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל דָּפַק וְהֵצִיץ וְזָרַח, וּמָשׁ חֲצִי הָהָר מִמִּזְרָח, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל הֵקִים מִלּוּל נוֹאֲמוֹ, וּבָא הוּא וְכָל קְדוֹשָׁיו עִמּוֹ, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל וּלְכָל בָּאֵי עוֹלָם, בַּת קוֹל יִשָּׁמַע בָּעוֹלָם, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל זֶרַע עֲמוּסֵי רְחָמוֹ, נוֹלְדוּ כְּיֶלֶד מִמְּעֵי אִמּוֹ, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל חָלָה וְיָלְדָה מִי זֹאת, מִי שָׁמַע כָּזֹאת, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל טָהוֹר פָּעַל כָּל אֵלֶּה, וּמִי רָאָה כָּאֵלֶּה, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל יֶשַׁע וּזְמָן הוּחָד, הֲיוּחַל אֶרֶץ בְּיוֹם אֶחָד, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל כַּבִּיר רוּם וָתַחַת, אִם יִוָּלֶד גּוֹי פַּעַם אֶחָת, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל לְעֵת יִגְאַל עַמּוֹ נָאוֹר, וְהָיָה לְעֵת עֶרֶב יִהְיֶה אוֹר, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל מוֹשִׁיעִים יַעֲלוּ לְהַר צִיּוֹן, כִּי חָלָה גַּם יָלְדָה צִיּוֹן, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל נִשְׁמַע בְּכָל גְּבוּלֵךְ, הַרְחִיבִי מְקוֹם אָהֳלֵךְ, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל שִׂימִי עַד דַּמֶּשֶׂק מִשְׁכְּנוֹתַיִךְ, קַבְּלִי בָנַיִךְ וּבְנוֹתַיִךְ, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל עִלְזִי חֲבַצֶּלֶת הַשָּׁרוֹן, כִּי קָמוּ יְשֵׁנֵי חֶבְרוֹן, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל פְּנוּ אֵלַי וְהִוָּשְׁעוּ, הַיּוֹם אִם בְּקוֹלִי תִשְׁמָעוּ, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל צָמַח אִישׁ צֶמַח שְׁמוֹ, הוּא דָּוִד בְּעַצְמוֹ, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל קוּמוּ כְּפוּשֵׁי עָפָר, הָקִיצוּ וְרַנְּנוּ שׁוֹכְנֵי עָפָר, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל רַבָּתִי עָם בְּהַמְלִיכוֹ, מִגְדּוֹל יְשׁוּעוֹת מַלְכּוֹ, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל שֵׁם רְשָׁעִים לְהַאֲבִיד, עֹשֶׂה חֶסֶד לִמְשִׁיחוֹ לְדָוִד, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל תְּנָה יְשׁוּעוֹת לְעַם עוֹלָם, לְדָוִד וּלְזַרְעוֹ עַד עוֹלָם, מְבַשֵּׂר וְאוֹמֵר.","cond":["sucot","hoshanaraba"]},{"kind":"instruction","text":"חזן וקהל:","cond":["sucot","hoshanaraba"]},{"kind":"text","text":"קוֹל מְבַשֵּׂר מְבַשֵּׂר וְאוֹמֵר.\nקוֹל מְבַשֵּׂר מְבַשֵּׂר וְאוֹמֵר.\nקוֹל מְבַשֵּׂר מְבַשֵּׂר וְאוֹמֵר.","cond":["sucot","hoshanaraba"]},{"kind":"instruction","text":"חובטים את הערבות חמש פעמים ואומרים:","cond":["sucot","hoshanaraba"]},{"kind":"text","text":"הוֹשִׁיעָה אֶת עַמֶּךָ, וּבָרֵךְ אֶת נַחֲלָתֶךָ, וּרְעֵם וְנַשְּׂאֵם עַד הָעוֹלָם: וְיִהְיוּ דְּבָרַי אֵלֶּה אֲשֶׁר הִתְחַנַּנְתִּי לִפְנֵי יהוה, קְרוֹבִים אֶל יהוה אֱלֹהֵינוּ יוֹמָם וָלָיְלָה, לַעֲשׂוֹת מִשְׁפַּט עַבְדּוֹ וּמִשְׁפַּט עַמּוֹ יִשְׂרָאֵל דְּבַר יוֹם בְּיוֹמוֹ: לְמַעַן דַּעַת כָּל עַמֵּי הָאָרֶץ, כִּי יהוה הוּא הָאֱלֹהִים אֵין עוֹד:","cond":["sucot"]},{"kind":"instruction","text":"מחזירים את ספר התורה לארון הקודש.","cond":["sucot","noHoshanaraba"]},{"kind":"instruction","text":"מחזירים את ספרי התורה ואומרים תחינה זו. יש אומרים את התחינה לאחר הקדיש.","cond":["sucot","hoshanaraba"]},{"kind":"text","text":"יְהִי רָצוֹן מִלְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, הַבּוֹחֵר בִּנְבִיאִים טוֹבִים וּבְמִנְהָגֵיהֶם הַטּוֹבִים, שֶׁתְּקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ וַהֲקָפוֹתֵינוּ, וּזְכָר לָנוּ זְכוּת שִׁבְעַת תְּמִימֶיךָ, וְתָסִיר מְחִיצַת הַבַּרְזֶל הַמַּפְסֶקֶת בֵּינֵינוּ וּבֵינֶיךָ, וְתַאֲזִין שַׁוְעָתֵנוּ, וְתֵיטִיב לָנוּ הַחֲתִימָה, תּוֹלֶה אֶרֶץ עַל בְּלִימָה, וְחָתְמֵנוּ בְּסֵפֶר חַיִּים טוֹבִים. וְהַיּוֹם הַזֶּה תִּתֵּן בִּשְׁכִינַת עֻזֶּךָ חָמֵשׁ גְּבוּרוֹת מְמֻתָּקוֹת, עַל יְדֵי חֲבִיטַת עֲרָבָה מִנְהַג נְבִיאֶיךָ הַקְּדוֹשִׁים, וְתִתְעוֹרֵר הָאַהֲבָה בֵּינֵיהֶם, וּתְנַשְּׁקֵנוּ מִנְּשִׁיקוֹת פִּיךָ, מַמְתֶּקֶת כָּל הַגְּבוּרוֹת וְכָל הַדִּינִין, וְתָאִיר לִשְׁכִינַת עֻזֶּךָ בְּשֵׁם (יו\"ד ה\"א וא\"ו) שֶׁהוּא טַל אוֹרוֹת טַלֶּךָ, וּמִשָּׁם תַּשְׁפִּיעַ שֶׁפַע לְעַבְדְּךָ הַמִּתְפַּלֵּל לְפָנֶיךָ, שֶׁתַּאֲרִיךְ יָמָיו וְתִמְחַל לוֹ חֲטָאָיו וַעֲוׂנוֹתָיו וּפְשָׁעָיו, וְתִפְשֹׁט יְמִינְךָ וְיָדְךָ לְקַבְּלוֹ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ. וְאוֹצָרְךָ הַטּוֹב תִּפְתַּח לְהַשְׂבִּיעַ מַיִם נֶפֶשׁ שׁוֹקֵקָה, כְּמוֹ שֶׁכָּתוּב: יִפְתַּח יהוה לְךָ אֶת אוֹצָרוֹ הַטּוֹב אֶת הַשָּׁמַיִם, לָתֵת מְטַר אַרְצְךָ בְּעִתּוֹ, וּלְבָרֵךְ אֶת כָּל מַעֲשֵׂה יָדֶךָ. אָמֵן.","cond":["sucot","hoshanaraba"]},{"kind":"instruction","text":"קדיש תתקבל","cond":["noTishaaBeav"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":["noTishaaBeav"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noTishaaBeav","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noTishaaBeav","ayt"]},{"kind":"text","text":"תִּתְקַבַּל צְלוֹתְהוֹן וּבָעוּתְהוֹן דְּכָל יִשְׂרָאֵל קֳדָם אֲבוּהוֹן דִּי בִשְׁמַיָּא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noTishaaBeav"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noTishaaBeav","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noTishaaBeav","ayt"]},{"kind":"instruction","text":"קדיש שלם (ללא תתקבל)","cond":["tishaaBeav"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":["tishaaBeav"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","ayt"]},{"kind":"header","text":"עלינו לשבח","cond":[]},{"kind":"text","text":"עָלֵינוּ לְשַׁבֵּחַ לַאֲדוֹן הַכֹּל, לָתֵת גְּדֻלָּה לְיוֹצֵר בְּרֵאשִׁית, שֶׁלֹּא עָשָׂנוּ כְּגוֹיֵי הָאֲרָצוֹת, וְלֹא שָׂמָנוּ כְּמִשְׁפְּחוֹת הָאֲדָמָה. שֶׁלֹּא שָׂם חֶלְקֵנוּ כָּהֶם, וְגוֹרָלֵנוּ כְּכָל-הֲמוֹנָם, שֶׁהֵם מִשְׁתַּחֲוִים לְהֶבֶל וָרִיק, וּמִתְפַּלְּלִים אֶל אֵל לֹא יוֹשִׁיעַ. וַאֲנַחְנוּ כּוֹרְעִים וּמִשְׁתַּחֲוִים וּמוֹדִים לִפְנֵי מֶלֶךְ מַלְכֵי הַמְּלָכִים הַקָּדוֹשׁ בָּרוּךְ הוּא, שֶׁהוּא נוֹטֶה שָׁמַיִם וְיוֹסֵד אָרֶץ, וּמוֹשַׁב יְקָרוֹ בַּשָּׁמַיִם מִמַּעַל, וּשְׁכִינַת עֻזּוֹ בְּגָבְהֵי מְרוֹמִים. הוּא אֱלֹהֵינוּ, אֵין עוֹד, אֱמֶת מַלְכֵּנוּ, אֶפֶס זוּלָתוֹ, כַּכָּתוּב בְּתוֹרָתוֹ: וְיָדַעְתָּ הַיּוֹם וַהֲשֵׁבֹתָ אֶל לְבָבֶךָ כִּי יהוה הוּא הָאֱלֹהִים בַּשָּׁמַיִם מִמַּעַל וְעַל הָאָרֶץ מִתָּחַת אֵין עוֹד:","cond":[]},{"kind":"text","text":"עַל כֵּן נְקַוֶּה לְךָ יהוה אֱלֹהֵינוּ, לִרְאוֹת מְהֵרָה בְּתִפְאֶרֶת עֻזֶּךָ, לְהַעֲבִיר גִּלּוּלִים מִן הָאָרֶץ, וְהָאֱלִילִים כָּרוֹת יִכָּרֵתוּן, לְתַקֵּן עוֹלָם בְּמַלְכוּת שַׁדַּי, וְכָל בְּנֵי בָשָׂר יִקְרְאוּ בִשְׁמֶךָ, לְהַפְנוֹת אֵלֶיךָ כָּל רִשְׁעֵי אָרֶץ. יַכִּירוּ וְיֵדְעוּ כָּל יוֹשְׁבֵי תֵבֵל, כִּי לְךָ תִכְרַע כָּל בֶּרֶךְ, תִּשָּׁבַע כָּל לָשׁוֹן. לְפָנֶיךָ יהוה אֱלֹהֵינוּ יִכְרְעוּ וְיִפֹּלוּ, וְלִכְבוֹד שִׁמְךָ יְקָר יִתֵּנוּ, וִיקַבְּלוּ כֻלָּם אֶת עֹל מַלְכוּתֶךָ, וְתִמְלֹךְ עֲלֵיהֶם מְהֵרָה לְעוֹלָם וָעֶד. כִּי הַמַּלְכוּת שֶׁלְּךָ הִיא, וּלְעוֹלְמֵי עַד תִּמְלֹךְ בְּכָבוֹד, כַּכָּתוּב בְּתוֹרָתֶךָ: יהוה יִמְלֹךְ לְעֹלָם וָעֶד: וְנֶאֱמַר: וְהָיָה יהוה לְמֶלֶךְ עַל כָּל הָאָרֶץ בַּיּוֹם הַהוּא יִהְיֶה יהוה אֶחָד וּשְׁמוֹ אֶחָד:","cond":[]},{"kind":"text","text":"אַל תִּירָא מִפַּחַד פִּתְאֹם וּמִשֹּׁאַת רְשָׁעִים כִּי תָבֹא: עֻצוּ עֵצָה וְתֻפָר, דַּבְּרוּ דָבָר וְלֹא יָקוּם, כִּי עִמָּנוּ אֵל: וְעַד זִקְנָה אֲנִי הוּא, וְעַד שֵׂיבָה אֲנִי אֶסְבֹּל אֲנִי עָשִׂיתִי וַאֲנִי אֶשָּׂא וַאֲנִי אֶסְבֹּל וַאֲמַלֵּט:","cond":[]},{"kind":"instruction","text":"קדיש יתום","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":[]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"header","text":"שיר של יום","cond":["noTishaaBeav"]},{"kind":"instruction","text":"שיר של יום","cond":["noTishaaBeav"]},{"kind":"text","text":"הַיּוֹם יוֹם רִאשׁוֹן בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["noTishaaBeav","sun"]},{"kind":"text","text":"לְדָוִד מִזְמוֹר, לַיהוה הָאָרֶץ וּמְלוֹאָהּ, תֵּבֵל וְיֹשְׁבֵי בָהּ: כִּי הוּא עַל יַמִּים יְסָדָהּ, וְעַל נְהָרוֹת יְכוֹנְנֶהָ: מִי יַעֲלֶה בְהַר יהוה, וּמִי יָקוּם בִּמְקוֹם קָדְשׁוֹ: נְקִי כַפַּיִם וּבַר לֵבָב, אֲשֶׁר לֹא נָשָׂא לַשָּׁוְא נַפְשִׁי וְלֹא נִשְׁבַּע לְמִרְמָה: יִשָּׂא בְרָכָה מֵאֵת יהוה, וּצְדָקָה מֵאֱלֹהֵי יִשְׁעוֹ: זֶה דּוֹר דֹּרְשָׁיו, מְבַקְשֵׁי פָנֶיךָ יַעֲקֹב סֶלָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וְהִנָּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבוֹא מֶלֶךְ הַכָּבוֹד: מִי זֶה מֶלֶךְ הַכָּבוֹד, יהוה עִזּוּז וְגִבּוֹר, יהוה גִּבּוֹר מִלְחָמָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבֹא מֶלֶךְ הַכָּבוֹד: מִי הוּא זֶה מֶלֶךְ הַכָּבוֹד, יהוה צְבָאוֹת הוּא מֶלֶךְ הַכָּבוֹד סֶלָה:","cond":["noTishaaBeav","sun"]},{"kind":"text","text":"הַיּוֹם יוֹם שֵׁנִי בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["noTishaaBeav","mon"]},{"kind":"text","text":"שִׁיר מִזְמוֹר לִבְנֵי קֹרַח: גָּדוֹל יהוה וּמְהֻלָּל מְאֹד בְּעִיר אֱלֹהֵינוּ הַר קָדְשׁוֹ: יְפֵה נוֹף, מְשׂוֹשׂ כָּל הָאָרֶץ, הַר צִיּוֹן יַרְכְּתֵי צָפוֹן קִרְיַת מֶלֶךְ רָב: אֱלֹהִים בְּאַרְמְנוֹתֶיהָ נוֹדַע לְמִשְׂגָּב: כִּי הִנֵּה הַמְּלָכִים נוֹעֲדוּ עָבְרוּ יַחְדָּו: הֵמָּה רָאוּ כֵּן תָּמָהוּ, נִבְהֲלוּ נֶחְפָּזוּ: רְעָדָה אֲחָזָתַם שָׁם, חִיל כַּיּוֹלֵדָה: בְּרוּחַ קָדִים תְּשַׁבֵּר אֳנִיּוֹת תַּרְשִׁישׁ: כַּאֲשֶׁר שָׁמַעְנוּ כֵּן רָאִינוּ בְּעִיר יהוה צְבָאוֹת בְּעִיר אֱלֹהֵינוּ, אֱלֹהִים יְכוֹנְנֶהָ עַד עוֹלָם סֶלָה: דִּמִּינוּ אֱלֹהִים חַסְדֶּךָ בְּקֶרֶב הֵיכָלֶךָ: כְּשִׁמְךָ אֱלֹהִים כֵּן תְּהִלָּתְךָ עַל קַצְוֵי אֶרֶץ, צֶדֶק מָלְאָה יְמִינֶךָ: יִשְׂמַח הַר צִיּוֹן, תָּגֵלְנָה בְּנוֹת יְהוּדָה, לְמַעַן מִשְׁפָּטֶיךָ: סֹבּוּ צִיּוֹן וְהַקִּיפוּהָ, סִפְרוּ מִגְדָּלֶיהָ: שִׁיתוּ לִבְּכֶם לְחֵילָה, פַּסְּגוּ אַרְמְנוֹתֶיהָ, לְמַעַן תְּסַפְּרוּ לְדוֹר אַחֲרוֹן: כִּי זֶה אֱלֹהִים אֱלֹהֵינוּ עוֹלָם וָעֶד, הוּא יְנַהֲגֵנוּ עַל מוּת:","cond":["noTishaaBeav","mon"]},{"kind":"text","text":"הַיּוֹם יוֹם שְׁלִישִׁי בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["noTishaaBeav","tue"]},{"kind":"text","text":"מִזְמוֹר לְאָסָף, אֱלֹהִים נִצָּב בַּעֲדַת אֵל, בְּקֶרֶב אֱלֹהִים יִשְׁפֹּט: עַד מָתַי תִּשְׁפְּטוּ עָוֶל וּפְנֵי רְשָׁעִים תִּשְׂאוּ סֶלָה: שִׁפְטוּ דַל וְיָתוֹם, עָנִי וָרָשׁ הַצְדִּיקוּ: פַּלְּטוּ דַל וְאֶבְיוֹן, מִיַּד רְשָׁעִים הַצִּילוּ: לֹא יָדְעוּ וְלֹא יָבִינוּ, בַּחֲשֵׁכָה יִתְהַלָּכוּ, יִמּוֹטוּ כָּל מוֹסְדֵי אָרֶץ: אֲנִי אָמַרְתִּי אֱלֹהִים אַתֶּם וּבְנֵי עֶלְיוֹן כֻּלְּכֶם: אָכֵן כְּאָדָם תְּמוּתוּן וּכְאַחַד הַשָּׂרִים תִּפֹּלוּ: קוּמָה אֱלֹהִים שָׁפְטָה הָאָרֶץ, כִּי אַתָּה תִנְחַל בְּכָל הַגּוֹיִם:","cond":["noTishaaBeav","tue"]},{"kind":"text","text":"הַיּוֹם יוֹם רְבִיעִי בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["noTishaaBeav","wed"]},{"kind":"text","text":"אֵל נְקָמוֹת יהוה, אֵל נְקָמוֹת הוֹפִיעַ: הִנָּשֵׂא שֹׁפֵט הָאָרֶץ, הָשֵׁב גְּמוּל עַל גֵּאִים: עַד מָתַי רְשָׁעִים, יהוה, עַד מָתַי רְשָׁעִים יַעֲלֹזוּ: יַבִּיעוּ יְדַבְּרוּ עָתָק, יִתְאַמְּרוּ כָּל פֹעֲלֵי אָוֶן: עַמְּךָ יהוה יְדַכְּאוּ, וְנַחֲלָתְךָ יְעַנּוּ: אַלְמָנָה וְגֵר יַהֲרֹגוּ, וִיתוֹמִים יְרַצֵּחוּ: וַיֹּאמְרוּ לֹא יִרְאֶה יָהּ, וְלֹא יָבִין אֱלֹהֵי יַעֲקֹב: בִּינוּ בֹּעֲרִים בָּעָם, וּכְסִילִים מָתַי תַּשְׂכִּילוּ: הַנֹּטַע אֹזֶן הֲלֹא יִשְׁמָע, אִם יֹצֵר עַיִן הֲלֹא יַבִּיט: הֲיֹסֵר גּוֹיִם הֲלֹא יוֹכִיחַ, הַמְלַמֵּד אָדָם דָּעַת: יהוה יֹדֵעַ מַחְשְׁבוֹת אָדָם כִּי הֵמָּה הָבֶל: אַשְׁרֵי הַגֶּבֶר אֲשֶׁר תְּיַסְּרֶנּוּ יָּהּ, וּמִתּוֹרָתְךָ תְלַמְּדֶנּוּ: לְהַשְׁקִיט לוֹ מִימֵי רָע, עַד יִכָּרֶה לָרָשָׁע שָׁחַת: כִּי לֹא יִטֹּשׁ יהוה עַמּוֹ, וְנַחֲלָתוֹ לֹא יַעֲזֹב: כִּי עַד צֶדֶק יָשׁוּב מִשְׁפָּט, וְאַחֲרָיו כָּל יִשְׁרֵי לֵב: מִי יָקוּם לִי עִם מְרֵעִים, מִי יִתְיַצֵּב לִי עִם פֹּעֲלֵי אָוֶן: לוּלֵי יהוה עֶזְרָתָה לִּי, כִּמְעַט שָׁכְנָה דוּמָה נַפְשִׁי: אִם אָמַרְתִּי מָטָה רַגְלִי, חַסְדְּךָ יהוה יִסְעָדֵנִי: בְּרֹב שַׂרְעַפַּי בְּקִרְבִּי, תַּנְחוּמֶיךָ יְשַׁעַשְׁעוּ נַפְשִׁי: הַיְחָבְרְךָ כִּסֵּא הַוּוֹת, יֹצֵר עָמָל עֲלֵי חֹק: יָגוֹדּוּ עַל נֶפֶשׁ צַדִּיק, וְדָם נָקִי יַרְשִׁיעוּ: וַיְהִי יהוה לִי לְמִשְׂגָּב, וֵאלֹהַי לְצוּר מַחְסִי: וַיָּשֶׁב עֲלֵיהֶם אֶת אוֹנָם וּבְרָעָתָם יַצְמִיתֵם, יַצְמִיתֵם יהוה אֱלֹהֵינוּ:\nלְכוּ נְרַנְּנָה לַיהוה, נָרִיעָה לְצוּר יִשְׁעֵנוּ: נְקַדְּמָה פָנָיו בְּתוֹדָה, בִּזְמִרוֹת נָרִיעַ לוֹ: כִּי אֵל גָּדוֹל יהוה, וּמֶלֶךְ גָּדוֹל עַל כָּל אֱלֹהִים:","cond":["noTishaaBeav","wed"]},{"kind":"text","text":"הַיּוֹם יוֹם חֲמִישִׁי בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["noTishaaBeav","thu"]},{"kind":"text","text":"לַמְנַצֵּחַ עַל הַגִּתִּית לְאָסָף: הַרְנִינוּ לֵאלֹהִים עֻזֵּנוּ, הָרִיעוּ לֵאלֹהֵי יַעֲקֹב: שְׂאוּ זִמְרָה וּתְנוּ תֹף, כִּנּוֹר נָעִים עִם נָבֶל: תִּקְעוּ בַחֹדֶשׁ שׁוֹפָר, בַּכֵּסֶה לְיוֹם חַגֵּנוּ: כִּי חֹק לְיִשְׂרָאֵל הוּא, מִשְׁפָּט לֵאלֹהֵי יַעֲקֹב: עֵדוּת בִּיהוֹסֵף שָׂמוֹ בְּצֵאתוֹ עַל אֶרֶץ מִצְרָיִם, שְׂפַת לֹא יָדַעְתִּי אֶשְׁמָע: הֲסִירוֹתִי מִסֵּבֶל שִׁכְמוֹ, כַּפָּיו מִדּוּד תַּעֲבֹרְנָה: בַּצָּרָה קָרָאתָ וָאֲחַלְּצֶךָּ, אֶעֶנְךָ בְּסֵתֶר רַעַם, אֶבְחָנְךָ עַל מֵי מְרִיבָה סֶלָה: שְׁמַע עַמִּי וְאָעִידָה בָּךְ, יִשְׂרָאֵל אִם תִּשְׁמַע לִי: לֹא יִהְיֶה בְךָ אֵל זָר, וְלֹא תִשְׁתַּחֲוֶה לְאֵל נֵכָר: אָנֹכִי יהוה אֱלֹהֶיךָ הַמַּעַלְךָ מֵאֶרֶץ מִצְרָיִם, הַרְחֶב פִּיךָ וַאֲמַלְאֵהוּ: וְלֹא שָׁמַע עַמִּי לְקוֹלִי, וְיִשְׂרָאֵל לֹא אָבָה לִי: וָאֲשַׁלְּחֵהוּ בִּשְׁרִירוּת לִבָּם, יֵלְכוּ בְּמוֹעֲצוֹתֵיהֶם: לוּ עַמִּי שֹׁמֵעַ לִי, יִשְׂרָאֵל בִּדְרָכַי יְהַלֵּכוּ: כִּמְעַט אוֹיְבֵיהֶם אַכְנִיעַ, וְעַל צָרֵיהֶם אָשִׁיב יָדִי: מְשַׂנְאֵי יהוה יְכַחֲשׁוּ לוֹ, וִיהִי עִתָּם לְעוֹלָם: וַיַּאֲכִילֵהוּ מֵחֵלֶב חִטָּה, וּמִצּוּר, דְּבַשׁ אַשְׂבִּיעֶךָ:","cond":["noTishaaBeav","thu"]},{"kind":"text","text":"הַיּוֹם יוֹם שִׁשִּׁי בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["noTishaaBeav","fri"]},{"kind":"text","text":"יהוה מָלָךְ גֵּאוּת לָבֵשׁ, לָבֵשׁ יהוה עֹז הִתְאַזָּר, אַף תִּכּוֹן תֵּבֵל בַּל תִּמּוֹט: נָכוֹן כִּסְאֲךָ מֵאָז, מֵעוֹלָם אָתָּה: נָשְׂאוּ נְהָרוֹת, יהוה, נָשְׂאוּ נְהָרוֹת קוֹלָם, יִשְׂאוּ נְהָרוֹת דָכְיָם: מִקֹּלוֹת מַיִם רַבִּים, אַדִּירִים מִשְׁבְּרֵי יָם, אַדִּיר בַּמָּרוֹם יהוה: עֵדֹתֶיךָ נֶאֶמְנוּ מְאֹד לְבֵיתְךָ נַאֲוָה קֹדֶשׁ, יהוה, לְאֹרֶךְ יָמִים:","cond":["noTishaaBeav","fri"]},{"kind":"special","text":"בָּרְכִי נַפְשִׁי אֶת יהוה, יהוה אֱלֹהַי גָּדַלְתָּ מְּאֹד, הוֹד וְהָדָר לָבָשְׁתָּ:\nעֹטֶה אוֹר כַּשַּׂלְמָה נוֹטֶה שָׁמַיִם כַּיְרִיעָה:\nהַמְקָרֶה בַמַּיִם עֲלִיּוֹתָיו, הַשָּׂם עָבִים רְכוּבוֹ, הַמְהַלֵּךְ עַל כַּנְפֵי רוּחַ:\nעֹשֶׂה מַלְאָכָיו רוּחוֹת, מְשָׁרְתָיו אֵשׁ לֹהֵט:\nיָסַד אֶרֶץ עַל מְכוֹנֶיהָ, בַּל תִּמּוֹט עוֹלָם וָעֶד:\nתְּהוֹם כַּלְּבוּשׁ כִּסִּיתוֹ, עַל הָרִים יַעַמְדוּ מָיִם:\nמִן גַּעֲרָתְךָ יְנוּסוּן, מִן קוֹל רַעַמְךָ יֵחָפֵזוּן:\nיַעֲלוּ הָרִים, יֵרְדוּ בְקָעוֹת, אֶל מְקוֹם זֶה יָסַדְתָּ לָהֶם:\nגְּבוּל שַׂמְתָּ בַּל יַעֲבֹרוּן, בַּל יְשׁוּבוּן לְכַסּוֹת הָאָרֶץ:\nהַמְשַׁלֵּחַ מַעְיָנִים בַּנְּחָלִים בֵּין הָרִים יְהַלֵּכוּן:","cond":["noTishaaBeav","rh"]},{"kind":"special","text":"יַשְׁקוּ כָּל חַיְתוֹ שָׂדָי, יִשְׁבְּרוּ פְרָאִים צְמָאָם:\nעֲלֵיהֶם עוֹף הַשָּׁמַיִם יִשְׁכּוֹן, מִבֵּין עֳפָאיִם יִתְּנוּ קוֹל:\nמַשְׁקֶה הָרִים מֵעֲלִיּוֹתָיו, מִפְּרִי מַעֲשֶׂיךָ תִּשְׂבַּע הָאָרֶץ:\nמַצְמִיחַ חָצִיר לַבְּהֵמָה וְעֵשֶׂב לַעֲבֹדַת הָאָדָם, לְהוֹצִיא לֶחֶם מִן הָאָרֶץ:\nוְיַיִן יְשַׂמַּח לְבַב אֱנוֹשׁ, לְהַצְהִיל פָּנִים מִשָּׁמֶן, וְלֶחֶם לְבַב אֱנוֹשׁ יִסְעָד:\nיִשְׂבְּעוּ עֲצֵי יהוה, אַרְזֵי לְבָנוֹן אֲשֶׁר נָטָע:\nאֲשֶׁר שָׁם צִפֳּרִים יְקַנֵּנוּ, חֲסִידָה בְּרוֹשִׁים בֵּיתָהּ:\nהָרִים הַגְּבֹהִים לַיְּעֵלִים, סְלָעִים מַחְסֶה לַשְׁפַנִּים:\nעָשָׂה יָרֵחַ לְמוֹעֲדִים, שֶׁמֶשׁ יָדַע מְבוֹאוֹ:\nתָּשֶׁת חֹשֶׁךְ וִיהִי לָיְלָה, בּוֹ תִרְמֹשׂ כָּל חַיְתוֹ יָעַר:\nהַכְּפִירִים שֹׁאֲגִים לַטָּרֶף וּלְבַקֵּשׁ מֵאֵל אָכְלָם:\nתִּזְרַח הַשֶּׁמֶשׁ יֵאָסֵפוּן וְאֶל מְעוֹנֹתָם יִרְבָּצוּן:","cond":["noTishaaBeav","rh"]},{"kind":"special","text":"יֵצֵא אָדָם לְפָעֳלוֹ וְלַעֲבֹדָתוֹ עֲדֵי עָרֶב:\nמָה רַבּוּ מַעֲשֶׂיךָ יהוה, כֻּלָּם בְּחָכְמָה עָשִׂיתָ, מָלְאָה הָאָרֶץ קִנְיָנֶךָ:\nזֶה הַיָּם גָּדוֹל וּרְחַב יָדָיִם, שָׁם רֶמֶשׂ וְאֵין מִסְפָּר, חַיּוֹת קְטַנּוֹת עִם גְּדֹלוֹת:\nשָׁם אֳנִיּוֹת יְהַלֵּכוּן, לִוְיָתָן זֶה יָצַרְתָּ לְשַׂחֶק בּוֹ:\nכֻּלָּם אֵלֶיךָ יְשַׂבֵּרוּן לָתֵת אָכְלָם בְּעִתּוֹ:\nתִּתֵּן לָהֶם יִלְקֹטוּן, תִּפְתַּח יָדְךָ יִשְׂבְּעוּן טוֹב:\nתַּסְתִּיר פָּנֶיךָ יִבָּהֵלוּן, תֹּסֵף רוּחָם יִגְוָעוּן וְאֶל עֲפָרָם יְשׁוּבוּן:\nתְּשַׁלַּח רוּחֲךָ יִבָּרֵאוּן וּתְחַדֵּשׁ פְּנֵי אֲדָמָה:\nיְהִי כְבוֹד יהוה לְעוֹלָם, יִשְׂמַח יהוה בְּמַעֲשָׂיו:\nהַמַּבִּיט לָאָרֶץ וַתִּרְעָד, יִגַּע בֶּהָרִים וְיֶעֱשָׁנוּ:\nאָשִׁירָה לַיהוה בְּחַיָּי, אֲזַמְּרָה לֵאלֹהַי בְּעוֹדִי:\nיֶעֱרַב עָלָיו שִׂיחִי, אָנֹכִי אֶשְׂמַח בַּיהוה:\nיִתַּמּוּ חַטָּאִים מִן הָאָרֶץ וּרְשָׁעִים עוֹד אֵינָם, בָּרְכִי נַפְשִׁי אֶת יהוה, הַלְלוּיָהּ:","cond":["noTishaaBeav","rh"]},{"kind":"instruction","text":"קדיש יתום","cond":["noTishaaBeav"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":["noTishaaBeav"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noTishaaBeav","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noTishaaBeav","ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noTishaaBeav"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noTishaaBeav","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noTishaaBeav","ayt"]},{"kind":"instruction","text":"סיום התפילה","cond":["noTishaaBeav"]},{"kind":"text","text":"קַוֵּה אֶל יהוה, חֲזַק וְיַאֲמֵץ לִבֶּךָ, וְקַוֵּה אֶל יהוה:\nאֵין קָדושׁ כַּיהוה, כִּי אֵין בִּלְתֶּךָ, וְאֵין צוּר כֵּאלֹהֵינוּ:\nכִּי מִי אֱלוֹהַּ מִבַּלְעֲדֵי יהוה, וּמִי צוּר זוּלָתִי אֱלֹהֵינוּ:\n\nאֵין כֵּאלֹהֵינוּ, אֵין כַּאדוֹנֵינוּ, אֵין כְּמַלְכֵּנוּ, אֵין כְּמוֹשִׁיעֵנוּ.\nמִי כֵאלֹהֵינוּ, מִי כַאדוֹנֵינוּ, מִי כְמַלְכֵּנוּ, מִי כְמוֹשִׁיעֵנוּ.\nנוֹדֶה לֵאלֹהֵינוּ, נוֹדֶה לַאדוֹנֵינוּ, נוֹדֶה לְמַלְכֵּנוּ, נוֹדֶה לְמוֹשִׁיעֵנוּ.\nבָּרוּךְ אֱלֹהֵינוּ, בָּרוּךְ אֲדוֹנֵינוּ, בָּרוּךְ מַלְכֵּנוּ, בָּרוּךְ מוֹשִׁיעֵנוּ.\nאַתָּה הוּא אֱלֹהֵינוּ, אַתָּה הוּא אֲדוֹנֵינוּ, אַתָּה הוּא מַלְכֵּנוּ, אַתָּה הוּא מוֹשִׁיעֵנוּ.\nאַתָּה הוּא שֶׁהִקְטִירוּ אֲבוֹתֵינוּ לְפָנֶיךָ אֶת קְטֹרֶת הַסַּמִים.","cond":["noTishaaBeav"]},{"kind":"instruction","text":"פיטום הקטורת","cond":["noTishaaBeav"]},{"kind":"text","text":"פִּטּוּם הַקְּטֹרֶת: הַצֳּרִי, וְהַצִּפֹּרֶן, הַחֶלְבְּנָה, וְהַלְּבוֹנָה, מִשְׁקַל שִׁבְעִים שִׁבְעִים מָנֶה, מֹר וּקְצִיעָה, שִׁבֹּלֶת נֵרְדְּ, וְכַרְכֹּם מִשְׁקַל שִׁשָּׁה עָשָׂר שִׁשָּׁה עָשָׂר מָנֶה, הַקֹּשְׁטְ שְׁנֵים עָשָׂר, וְקִלּוּפָה שְׁלֹשָׁה, קִנָּמוֹן תִּשְׁעָה, בֹּרִית כַּרְשִׁינָה תִּשְׁעָה קַבִּין. יֵין קַפְרִיסִין סְאִין תְּלָתָא וְקַבִּין תְּלָתָא, וְאִם אֵין לוֹ יֵין קַפְרִיסִין מֵבִיא חֲמַר חִוַּרִין עַתִּיק. מֶלַח סְדוֹמִית רֹבַע, מַעֲלֶה עָשָׁן כָּל שֶׁהוּא, רַבִּי נָתָן הַבַּבְלִי אוֹמֵר: אַף כִּפַּת הַיַּרְדֵּן כָּל שֶׁהוּא. וְאִם נָתַן בָּהּ דְּבַשׁ פְּסָלָהּ, וְאִם חִסַּר אַחַת מִכָּל סַמָּנֶיהָ חַיָּב מִיתָה.\n\nרַבָּן שִׁמְעוֹן בֶּן גַּמְלִיאֵל אוֹמֵר: הַצֳּרִי אֵינוֹ אֶלָּא שְׂרָף הַנּוֹטֵף מֵעֲצֵי הַקְּטָף. בֹּרִית כַּרְשִׁינָה שֶׁשָּׁפִין בָּהּ אֶת הַצִּפֹּרֶן כְּדֵי שֶׁתְּהֵא נָאָה, יֵין קַפְרִיסִין שֶׁשּׁוֹרִין בּוֹ אֶת הַצִּפֹּרֶן כְּדֵי שֶׁתְּהֵא עַזָּה. וַהֲלֹא מֵי רַגְלַיִם יָפִין לָהּ, אֶלָּא שֶׁאֵין מַכְנִיסִין מֵי רַגְלַיִם בַּמִקְדָּשׁ מִפְּנֵי הַכָּבוֹד.\n\nתָּנָא דְבֵי אֵלִיָּהוּ: כָּל הַשּׁוֹנֶה הֲלָכוֹת בְּכָל יוֹם מֻבְטָח לוֹ שֶׁהוּא בֶּן עוֹלָם הַבָּא, שֶׁנֶּאֱמַר: הֲלִיכוֹת עוֹלָם לוֹ: אַל תִּקְרֵי הֲלִיכות אֶלָּא הֲלָכוֹת. אָמַר רַבִּי אֶלְעָזָר אָמַר רַבִּי חֲנִינָא: תַּלְמִידֵי חֲכָמִים מַרְבִּים שָׁלוֹם בָּעוֹלָם, שֶׁנֶּאֱמַר: וְכָל בָּנַיִךְ לִמּוּדֵי יהוה וְרַב שְׁלוֹם בָּנָיִךְ: אַל תִּקְרֵי בָּנָיִךְ אֶלָּא בּוֹנָיִךְ. שָׁלוֹם רָב לְאֹהֲבֵי תוֹרָתֶךָ, וְאֵין לָמוֹ מִכְשׁוֹל: יְהִי שָׁלוֹם בְּחֵילֵךְ, שַׁלְוָה בְּאַרְמְנוֹתָיִךְ: לְמַעַן אַחַי וְרֵעָי אֲדַבְּרָה נָּא שָׁלוֹם בָּךְ: לְמַעַן בֵּית יהוה אֱלֹהֵינוּ אֲבַקְשָׁה טוֹב לָךְ: יהוה עֹז לְעַמּוֹ יִתֵּן, יהוה יְבָרֵךְ אֶת עַמּוֹ בַשָּׁלוֹם:","cond":["noTishaaBeav"]},{"kind":"instruction","text":"קדיש דרבנן","cond":["noTishaaBeav"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":["noTishaaBeav"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noTishaaBeav","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noTishaaBeav","ayt"]},{"kind":"text","text":"עַל יִשְׂרָאֵל וְעַל רַבָּנָן וְעַל תַּלְמִידֵיהוֹן וְעַל כָּל תַּלְמִידֵי תַלְמִידֵיהוֹן, וְעַל כָּל מָאן דְּעָסְקִין בְּאוֹרַיְתָא, דִּי בְאַתְרָא (קַדִּישָׁא) הָדֵין וְדִי בְכָל אֲתָר וַאֲתָר, יְהֵא לְהוֹן וּלְכוֹן שְׁלָמָא רַבָּא, חִנָּא וְחִסְדָּא, וְרַחֲמֵי וְחַיֵּי אֲרִיכֵי וּמְזוֹנֵי רְוִיחֵי וּפֻרְקָנָא מִן קֳדָם אֲבוּהוֹן דִּי בִשְׁמַיָּא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noTishaaBeav"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noTishaaBeav","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noTishaaBeav","ayt"]},{"kind":"instruction","text":"חזן:","cond":["noTora"]},{"kind":"text","text":"בָּרְכוּ אֶת יהוה הַמְבֹרָךְ.","cond":["noTora"]},{"kind":"instruction","text":"קהל וחזן:","cond":["noTora"]},{"kind":"text","text":"בָּרוּךְ יהוה הַמְבֹרָךְ לְעוֹלָם וָעֶד.","cond":["noTora"]},{"kind":"header","text":"לדוד","cond":["ledavid"]},{"kind":"special","text":"לְדָוִד, יהוה אוֹרִי וְיִשְׁעִי מִמִּי אִירָא, יהוה מָעוֹז חַיַּי מִמִּי אֶפְחָד: בִּקְרֹב עָלַי מְרֵעִים לֶאֱכֹל אֶת בְּשָׂרִי, צָרַי וְאֹיְבַי לִי, הֵמָּה כָשְׁלוּ וְנָפָלוּ: אִם תַּחֲנֶה עָלַי מַחֲנֶה לֹא יִירָא לִבִּי, אִם תָּקוּם עָלַי מִלְחָמָה בְּזֹאת אֲנִי בוֹטֵחַ: אַחַת שָׁאַלְתִּי מֵאֵת יהוה, אוֹתָהּ אֲבַקֵּשׁ, שִׁבְתִּי בְּבֵית יהוה כָּל יְמֵי חַיַּי, לַחֲזוֹת בְּנֹעַם יהוה וּלְבַקֵּר בְּהֵיכָלוֹ: כִּי יִצְפְּנֵנִי בְּסֻכֹּה בְּיוֹם רָעָה יַסְתִּירֵנִי בְּסֵתֶר אָהֳלוֹ, בְּצוּר יְרוֹמְמֵנִי: וְעַתָּה יָרוּם רֹאשִׁי עַל אֹיְבַי סְבִיבוֹתַי, וְאֶזְבְּחָה בְאָהֳלוֹ זִבְחֵי תְרוּעָה, אָשִׁירָה וַאֲזַמְּרָה לַיהוה: שְׁמַע יהוה קוֹלִי אֶקְרָא, וְחָנֵּנִי וַעֲנֵנִי: לְךָ אָמַר לִבִּי בַּקְּשׁוּ פָנַי, אֶת פָּנֶיךָ יהוה אֲבַקֵּשׁ: אַל תַּסְתֵּר פָּנֶיךָ מִמֶּנִּי, אַל תַּט בְּאַף עַבְדֶּךָ, עֶזְרָתִי הָיִיתָ, אַל תִּטְּשֵׁנִי וְאַל תַּעַזְבֵנִי אֱלֹהֵי יִשְׁעִי: כִּי אָבִי וְאִמִּי עֲזָבוּנִי, וַיהוה יַאַסְפֵנִי: הוֹרֵנִי יהוה דַּרְכֶּךָ וּנְחֵנִי בְּאֹרַח מִישׁוֹר לְמַעַן שׁוֹרְרָי: אַל תִּתְּנֵנִי בְּנֶפֶשׁ צָרָי, כִּי קָמוּ בִי עֵדֵי שֶׁקֶר וִיפֵחַ חָמָס: לוּלֵא הֶאֱמַנְתִּי לִרְאוֹת בְּטוּב יהוה בְּאֶרֶץ חַיִּים: קַוֵּה אֶל יהוה, חֲזַק וְיַאֲמֵץ לִבֶּךָ, וְקַוֵּה אֶל יהוה:","cond":["ledavid"]},{"kind":"instruction","text":"קדיש יתום","cond":["ledavid"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":["ledavid"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ledavid","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ledavid","ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ledavid"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ledavid","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ledavid","ayt"]},{"kind":"header","text":"מזמור לבית האבל","cond":[]},{"kind":"instruction","text":"בבית האבל אומרים מזמור זה:","cond":["shacharitTachanun"]},{"kind":"text","text":"לַמְנַצֵּחַ לִבְנֵי קֹרַח מִזְמוֹר: שִׁמְעוּ זֹאת כָּל הָעַמִּים, הַאֲזִינוּ כָּל יֹשְׁבֵי חָלֶד: גַּם בְּנֵי אָדָם, גַּם בְּנֵי אִישׁ, יַחַד עָשִׁיר וְאֶבְיוֹן: פִּי יְדַבֵּר חָכְמוֹת, וְהָגוּת לִבִּי תְבוּנוֹת: אַטֶּה לְמָשָׁל אָזְנִי, אֶפְתַּח בְּכִנּוֹר חִידָתִי: לָמָּה אִירָא בִּימֵי רָע, עֲוׂן עֲקֵבַי יְסוּבֵּנִי: הַבֹּטְחִים עַל חֵילָם, וּבְרֹב עָשְׁרָם יִתְהַלָּלוּ: אָח לֹא פָדֹה יִפְדֶּה אִישׁ, לֹא יִתֵּן לֵאלֹהִים כָּפְרוֹ: וְיֵקַר פִּדְיוֹן נַפְשָׁם, וְחָדַל לְעוֹלָם: וִיחִי עוֹד לָנֶצַח, לֹא יִרְאֶה הַשָּׁחַת: כִּי יִרְאֶה חֲכָמִים יָמוּתוּ, יַחַד כְּסִיל וָבַעַר יֹאבֵדוּ, וְעָזְבוּ לַאֲחֵרִים חֵילָם: קִרְבָּם בָּתֵּימוֹ לְעוֹלָם, מִשְׁכְּנֹתָם לְדֹר וָדֹר, קָרְאוּ בִשְׁמוֹתָם עֲלֵי אֲדָמוֹת: וְאָדָם בִּיקָר בַּל יָלִין, נִמְשַׁל כַּבְּהֵמוֹת נִדְמוּ: זֶה דַרְכָּם כֵּסֶל לָמוֹ, וְאַחֲרֵיהֶם בְּפִיהֶם יִרְצוּ סֶלָה: כַּצֹּאן לִשְׁאוֹל שַׁתּוּ מָוֶת יִרְעֵם, וַיִּרְדּוּ בָם יְשָׁרִים לַבֹּקֶר, וְצוּרָם לְבַלּוֹת שְׁאוֹל מִזְּבֻל לוֹ: אַךְ אֱלֹהִים יִפְדֶּה נַפְשִׁי מִיַּד שְׁאוֹל, כִּי יִקָּחֵנִי סֶלָה: אַל תִּירָא כִּי יַעֲשִׁר אִישׁ, כִּי יִרְבֶּה כְּבוֹד בֵּיתוֹ: כִּי לֹא בְמוֹתוֹ יִקַּח הַכֹּל, לֹא יֵרֵד אַחֲרָיו כְּבוֹדוֹ: כִּי נַפְשׁוֹ בְּחַיָּיו יְבָרֵךְ, וְיוֹדֻךָ כִּי תֵיטִיב לָךְ: תָּבוֹא עַד דּוֹר אֲבוֹתָיו, עַד נֵצַח לֹא יִרְאוּ אוֹר: אָדָם בִּיקָר וְלֹא יָבִין נִמְשַׁל כַּבְּהֵמוֹת נִדְמוּ:","cond":["shacharitTachanun"]},{"kind":"instruction","text":"בבית האבל אומרים מזמור זה:","cond":["noShacharitTachanun"]},{"kind":"text","text":"מִכְתָּם לְדָוִד, שָׁמְרֵנִי אֵל כִּי חָסִיתִי בָךְ: אָמַרְתְּ לַיהוה, אֲדֹנָי אָתָּה, טוֹבָתִי בַּל עָלֶיךָ: לִקְדוֹשִׁים אֲשֶׁר בָּאָרֶץ הֵמָּה, וְאַדִּירֵי כָּל חֶפְצִי בָם: יִרְבּוּ עַצְּבוֹתָם אַחֵר מָהָרוּ, בַּל אַסִּיךְ נִסְכֵּיהֶם מִדָּם, וּבַל אֶשָּׂא אֶת שְׁמוֹתָם עַל שְׂפָתָי: יהוה, מְנָת חֶלְקִי וְכוֹסִי, אַתָּה תּוֹמִיךְ גּוֹרָלִי: חֲבָלִים נָפְלוּ לִי בַּנְּעִמִים, אַף נַחֲלָת שָׁפְרָה עָלָי: אֲבָרֵךְ אֶת יהוה אֲשֶׁר יְעָצָנִי, אַף לֵילוֹת יִסְּרוּנִי כִלְיוֹתָי: שִׁוִּיתִי יהוה לְנֶגְדִּי תָמִיד, כִּי מִימִינִי בַּל אֶמּוֹט: לָכֵן שָׂמַח לִבִּי וַיָּגֶל כְּבוֹדִי, אַף בְּשָׂרִי יִשְׁכֹּן לָבֶטַח: כִּי לֹא תַעֲזֹב נַפְשִׁי לִשְׁאוֹל, לֹא תִתֵּן חֲסִידְךָ לִרְאוֹת שָׁחַת: תּוֹדִיעֵנִי אֹרַח חַיִּים, שֹׂבַע שְׂמָחוֹת אֶת פָּנֶיךָ, נְעִמוֹת בִּימִינְךָ נֶצַח:","cond":["noShacharitTachanun"]},{"kind":"instruction","text":"קדיש יתום","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":[]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"header","text":"שש זכירות","cond":[]},{"kind":"instruction","text":"שש זכירות\n\nיציאת מצרים:","cond":[]},{"kind":"text","text":"לְמַעַן תִּזְכֹּר אֶת-יוֹם צֵאתְךָ מֵאֶרֶץ מִצְרַיִם כֹּל יְמֵי חַיֶּיךָ:","cond":[]},{"kind":"instruction","text":"מעמד הר סיני:","cond":[]},{"kind":"text","text":"רַק הִשָּׁמֶר לְךָ וּשְׁמֹר נַפְשְׁךָ מְאֹד פֶּן-תִּשְׁכַּח אֶת-הַדְּבָרִים אֲשֶׁר-רָאוּ עֵינֶיךָ וּפֶן-יָסוּרוּ מִלְּבָבְךָ כֹּל יְמֵי חַיֶּיךָ, וְהוֹדַעְתָּם לְבָנֶיךָ וְלִבְנֵי בָנֶיךָ: יוֹם אֲשֶׁר עָמַדְתָּ לִפְנֵי יהוה אֱלֹהֶיךָ בְּחֹרֵב, בֶּאֱמֹר יהוה אֵלַי הַקְהֶל-לִי אֶת-הָעָם וְאַשְׁמִעֵם אֶת-דְּבָרָי, אֲשֶׁר יִלְמְדוּן לְיִרְאָה אֹתִי כָּל-הַיָּמִים אֲשֶׁר הֵם חַיִּים עַל-הָאֲדָמָה וְאֶת-בְּנֵיהֶם יְלַמֵּדוּן:","cond":[]},{"kind":"instruction","text":"מעשה עמלק ומחייתו:","cond":[]},{"kind":"text","text":"זָכוֹר אֵת אֲשֶׁר-עָשָׂה לְךָ עֲמָלֵק, בַּדֶּרֶךְ בְּצֵאתְכֶם מִמִּצְרָיִם: אֲשֶׁר קָרְךָ בַּדֶּרֶךְ וַיְזַנֵּב בְּךָ כָּל-הַנֶּחֱשָׁלִים אַחַרֶיךָ וְאַתָּה עָיֵף וְיָגֵעַ, וְלֹא יָרֵא אֱלֹהִים: וְהָיָה בְּהָנִיחַ יהוה אֱלֹהֶיךָ לְךָ מִכָּל-אֹיְבֶיךָ מִסָּבִיב, בָּאָרֶץ אֲשֶׁר-יהוה אֱלֹהֶיךָ נֹתֵן לְךָ נַחֲלָה לְרִשְׁתָּהּ, תִּמְחֶה אֶת-זֵכֶר עֲמָלֵק מִתַּחַת הַשָּׁמָיִם, לֹא תִּשְׁכָּח:","cond":[]},{"kind":"instruction","text":"מעשי אבותינו במדבר:","cond":[]},{"kind":"text","text":"זְכֹר אַל תִּשְׁכַּח אֵת אֲשֶׁר-הִקְצַפְתָּ אֶת יהוה אֱלֹהֶיךָ בַּמִּדְבָּר, לְמִן-הַיּוֹם אֲשֶׁר-יָצָאתָ מֵאֶרֶץ מִצְרַיִם עַד-בֹּאֲכֶם עַד-הַמָּקוֹם הַזֶּה, מַמְרִים הֱיִיתֶם עִם-יהוה:","cond":[]},{"kind":"instruction","text":"מעשה מרים:","cond":[]},{"kind":"text","text":"זָכוֹר אֵת אֲשֶׁר-עָשָׂה יהוה אֱלֹהֶיךָ לְמִרְיָם, בַּדֶּרֶךְ בְּצֵאתְכֶם מִמִּצְרָיִם:","cond":[]},{"kind":"instruction","text":"שבת:","cond":[]},{"kind":"text","text":"זָכוֹר אֶת-יוֹם הַשַּׁבָּת לְקַדְּשׁוֹ:","cond":[]},{"kind":"header","text":"י\"ג עיקרים","cond":[]},{"kind":"instruction","text":"שלשה עשר עקרים","cond":[]},{"kind":"text","text":"א. אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה, שֶׁהַבּוֹרֵא יִתְבָּרַךְ שְׁמוֹ הוּא בּוֹרֵא וּמַנְהִיג לְכָל הַבְּרוּאִים, וְהוּא לְבַדּו עָשָׂה וְעוֹשֶׂה וְיַעֲשֶׂה לְכָל הַמַּעֲשִׂים.\nב. אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה, שֶׁהַבּוֹרֵא יִתְבָּרַךְ שְׁמוֹ הוּא יָחִיד וְאֵין יְחִידוּת כָּמוֹהוּ בְּשׁוּם פָּנִים, וְהוּא לְבַדּוֹ אֱלֹהֵינוּ, הָיָה הֹוֶה וְיִהְיֶה.\nג. אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה, שֶׁהַבּוֹרֵא יִתְבָּרַךְ שְׁמוֹ אֵינוֹ גוּף, וְלֹא יַשִּׂיגוּהוּ מַשִּׂיגֵי הַגּוּף, וְאֵין לוֹ שׁוּם דִּמְיוֹן כְּלָל.\nד. אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה, שֶׁהַבּוֹרֵא יִתְבָּרַךְ שְׁמוֹ הוּא רִאשׁוֹן וְהוּא אַחֲרוֹן.\nה. אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה, שֶׁהַבּוֹרֵא יִתְבָּרַךְ שְׁמוֹ לוֹ לְבַדּוֹ רָאוּי לְהִתְפַּלֵּל, וְאֵין רָאוּי לְהִתְפַּלֵּל לְזוּלָתוֹ.\nו. אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה, שֶׁכָּל דִּבְרֵי נְבִיאִים אֱמֶת.\nז. אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה, שֶׁנְּבוּאַת מֹשֶׁה רַבֵּנוּ עָלָיו הַשָּׁלוֹם הָיְתָה אֲמִתִּית, וְשֶׁהוּא הָיָה אָב לַנְּבִיאִים, לַקּוֹדְמִים לְפָנָיו וְלַבָּאִים אַחֲרָיו.\nח. אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה, שֶׁכָּל הַתּוֹרָה הַמְּצוּיָה עַתָּה בְיָדֵינוּ הִיא הַנְּתוּנָה לְמֹשֶׁה רַבֵּנוּ עָלָיו הַשָּׁלוֹם.\nט. אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה, שֶׁזֹּאת הַתּוֹרָה לֹא תְהֵא מֻחְלֶפֶת וְלֹא תְהֵא תוֹרָה אַחֶרֶת מֵאֵת הַבּוֹרֵא יִתְבָּרַךְ שְׁמוֹ.\nי. אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה, שֶׁהַבּוֹרֵא יִתְבָּרַךְ שְׁמוֹ יוֹדֵעַ כָּל מַעֲשֵׂה בְנֵי אָדָם וְכָל מַחְשְׁבוֹתָם, שֶׁנֶּאֱמַר: הַיֹּצֵר יַחַד לִבָּם, הַמֵּבִין אֶל כָּל מַעֲשֵׂיהֶם:\nיא. אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה, שֶׁהַבּוֹרֵא יִתְבָּרַךְ שְׁמוֹ גּוֹמֵל טוֹב לְשׁוֹמְרֵי מִצְוׂתָיו וּמַעֲנִישׁ לְעוֹבְרֵי מִצְוׂתָיו.\nיב. אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה, בְּבִיאַת הַמָּשִׁיחַ, וְאַף עַל פִּי שֶׁיִּתְמַהְמֵהַּ, עִם כָּל זֶה אֲחַכֶּה לּוֹ בְּכָל יוֹם שֶׁיָּבוֹא.\nיג. אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה, שֶׁתִּהְיֶה תְּחִיַּת הַמֵּתִים בְּעֵת שֶׁיַעֲלֶה רָצוֹן מֵאֵת הַבּוֹרֵא יִתְבָּרַךְ שְׁמוֹ וְיִתְעַלֶּה זִכְרוֹ לָעַד וּלְנֵצַח נְצָחִים.","cond":[]}],"mincha":[{"kind":"header","text":"הנחת תפילין","cond":["tishaaBeav"]},{"kind":"instruction","text":"מתעטפים בטלית ומניחים תפילין, ואומרים קריאת שמע. ויש אומרים שעדיף שלא לומר קריאת שמע מפני איסור לימוד תורה.","cond":["tishaaBeav"]},{"kind":"text","text":"שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:","cond":["tishaaBeav"]},{"kind":"instruction","text":"בלחש:","cond":["tishaaBeav"]},{"kind":"text","text":"בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד.\n\nוְאָהַבְתָּ אֵת יהוה אֱלֹהֶיךָ, בְּכָל לְבָבְךָ וּבְכָל נַפְשְׁךָ וּבְכָל מְאֹדֶךָ: וְהָיוּ הַדְּבָרִים הָאֵלֶּה אֲשֶׁר אָנֹכִי מְצַוְּךָ הַיּוֹם, עַל לְבָבֶךָ: וְשִׁנַּנְתָּם לְבָנֶיךָ וְדִבַּרְתָּ בָּם, בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ: וּקְשַׁרְתָּם לְאוֹת עַל יָדֶךָ, וְהָיוּ לְטֹטָפֹת בֵּין עֵינֶיךָ: וּכְתַבְתָּם עַל מְזֻזוֹת בֵּיתֶךָ וּבִשְׁעָרֶיךָ:","cond":["tishaaBeav"]},{"kind":"text","text":"וְהָיָה אִם שָׁמֹעַ תִּשְׁמְעוּ אֶל מִצְוׂתַי, אֲשֶׁר אָנֹכִי מְצַוֶּה אֶתְכֶם הַיּוֹם, לְאַהֲבָה אֶת יהוה אֱלֹהֵיכֶם וּלְעָבְדוֹ, בְּכָל לְבַבְכֶם וּבְכָל נַפְשְׁכֶם: וְנָתַתִּי מְטַר אַרְצְכֶם בְּעִתּוֹ, יוֹרֶה וּמַלְקוֹשׁ, וְאָסַפְתָּ דְגָנֶךָ וְתִירֹשְׁךָ וְיִצְהָרֶךָ: וְנָתַתִּי עֵשֶׂב בְּשָׂדְךָ לִבְהֶמְתֶּךָ, וְאָכַלְתָּ וְשָׂבָעְתָּ: הִשָּׁמְרוּ לָכֶם פֶּן יִפְתֶּה לְבַבְכֶם, וְסַרְתֶּם וַעֲבַדְתֶּם אֱלֹהִים אֲחֵרִים וְהִשְׁתַּחֲוִיתֶם לָהֶם: וְחָרָה אַף יהוה בָּכֶם, וְעָצַר אֶת הַשָּׁמַיִם וְלֹא יִהְיֶה מָטָר, וְהָאֲדָמָה לֹא תִתֵּן אֶת יְבוּלָהּ, וַאֲבַדְתֶּם מְהֵרָה מֵעַל הָאָרֶץ הַטֹּבָה אֲשֶׁר יהוה נֹתֵן לָכֶם: וְשַׂמְתֶּם אֶת דְּבָרַי אֵלֶּה עַל לְבַבְכֶם וְעַל נַפְשְׁכֶם, וּקְשַׁרְתֶּם אֹתָם לְאוֹת עַל יֶדְכֶם וְהָיוּ לְטוֹטָפֹת בֵּין עֵינֵיכֶם: וְלִמַּדְתֶּם אֹתָם אֶת בְּנֵיכֶם לְדַבֵּר בָּם, בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ: וּכְתַבְתָּם עַל מְזוּזוֹת בֵּיתֶךָ וּבִשְׁעָרֶיךָ: לְמַעַן יִרְבּוּ יְמֵיכֶם וִימֵי בְנֵיכֶם עַל הָאֲדָמָה אֲשֶׁר נִשְׁבַּע יהוה לַאֲבֹתֵיכֶם לָתֵת לָהֶם, כִּימֵי הַשָּׁמַיִם עַל הָאָרֶץ:","cond":["tishaaBeav"]},{"kind":"text","text":"וַיֹּאמֶר יהוה אֶל מֹשֶׁה לֵּאמֹר: דַּבֵּר אֶל בְּנֵי יִשְׂרָאֵל וְאָמַרְתָּ אֲלֵהֶם, וְעָשׂוּ לָהֶם צִיצִת עַל כַּנְפֵי בִגְדֵיהֶם לְדֹרֹתָם, וְנָתְנוּ עַל צִיצִת הַכָּנָף פְּתִיל תְּכֵלֶת: וְהָיָה לָכֶם לְצִיצִת, וּרְאִיתֶם אֹתוֹ, וּזְכַרְתֶּם אֶת כָּל מִצְוׂת יהוה וַעֲשִׂיתֶם אֹתָם, וְלֹא תָתֻרוּ אַחֲרֵי לְבַבְכֶם וְאַחֲרֵי עֵינֵיכֶם אֲשֶׁר אַתֶּם זֹנִים אַחֲרֵיהֶם: לְמַעַן תִּזְכְּרוּ וַעֲשִׂיתֶם אֶת כָּל מִצְוׂתָי, וִהְיִיתֶם קְדֹשִׁים לֵאלֹהֵיכֶם: אֲנִי יהוה אֱלֹהֵיכֶם אֲשֶׁר הוֹצֵאתִי אֶתְכֶם מֵאֶרֶץ מִצְרַיִם, לִהְיוֹת לָכֶם לֵאלֹהִים, אֲנִי יהוה אֱלֹהֵיכֶם:","cond":["tishaaBeav"]},{"kind":"text","text":"אֱמֶת.","cond":["tishaaBeav"]},{"kind":"text","text":"אַשְׁרֵי יוֹשְׁבֵי בֵיתֶךָ עוֹד יְהַלְלוּךָ סֶּלָה:\nאַשְׁרֵי הָעָם שֶׁכָּכָה לּוֹ אַשְׁרֵי הָעָם שֶׁיהוה אֱלֹהָיו:\nתְּהִלָּה לְדָוִד, אֲרוֹמִמְךָ אֱלוֹהַי הַמֶּלֶךְ וַאֲבָרְכָה שִׁמְךָ לְעוֹלָם וָעֶד:\nבְּכָל יוֹם אֲבָרְכֶךָּ וַאֲהַלְלָה שִׁמְךָ לְעוֹלָם וָעֶד:\nגָּדוֹל יהוה וּמְהֻלָּל מְאֹד וְלִגְדֻלָּתוֹ אֵין חֵקֶר:\nדּוֹר לְדוֹר יְשַׁבַּח מַעֲשֶׂיךָ וּגְבוּרֹתֶיךָ יַגִּידוּ:\nהֲדַר כְּבוֹד הוֹדֶךָ וְדִבְרֵי נִפְלְאוֹתֶיךָ אָשִׂיחָה:\nוֶעֱזוּז נוֹרְאֹתֶיךָ יֹאמֵרוּ וּגְדוּלָּתְךָ אֲסַפְּרֶנָּה:\nזֵכֶר רַב טוּבְךָ יַבִּיעוּ וְצִדְקָתְךָ יְרַנֵּנוּ:","cond":[]},{"kind":"text","text":"חַנּוּן וְרַחוּם יהוה אֶרֶךְ אַפַּיִם וּגְדָל חָסֶד:\nטוֹב יהוה לַכֹּל וְרַחֲמָיו עַל כָּל מַעֲשָׂיו:\nיוֹדוּךָ יהוה כָּל מַעֲשֶׂיךָ וַחֲסִידֶיךָ יְבָרְכוּכָה:\nכְּבוֹד מַלְכוּתְךָ יֹאמֵרוּ וּגְבוּרָתְךָ יְדַבֵּרוּ:\nלְהוֹדִיעַ לִבְנֵי הָאָדָם גְּבוּרֹתָיו וּכְבוֹד הֲדַר מַלְכוּתוֹ:\nמַלְכוּתְךָ מַלְכוּת כָּל עֹלָמִים וּמֶמְשַׁלְתְּךָ בְּכָל דּוֹר וָדוֹר:\nסוֹמֵךְ יהוה לְכָל הַנֹּפְלִים וְזוֹקֵף לְכָל הַכְּפוּפִים:\nעֵינֵי כֹל אֵלֶיךָ יְשַׂבֵּרוּ וְאַתָּה נוֹתֵן לָהֶם אֶת אָכְלָם בְּעִתּוֹ:","cond":[]},{"kind":"text","text":"פּוֹתֵחַ אֶת יָדֶךָ וּמַשְׂבִּיעַ לְכָל חַי רָצוֹן:\nצַדִּיק יהוה בְּכָל דְּרָכָיו וְחָסִיד בְּכָל מַעֲשָׂיו:\nקָרוֹב יהוה לְכָל קֹרְאָיו לְכֹל אֲשֶׁר יִקְרָאֻהוּ בֶאֱמֶת:\nרְצוֹן יְרֵאָיו יַעֲשֶׂה וְאֶת שַׁוְעָתָם יִשְׁמַע וְיוֹשִׁיעֵם:\nשׁוֹמֵר יהוה אֶת כָּל אֹהֲבָיו וְאֵת כָּל הָרְשָׁעִים יַשְׁמִיד:\nתְּהִלַּת יהוה יְדַבֶּר פִּי וִיבָרֵךְ כָּל בָּשָׂר שֵׁם קָדְשׁוֹ לְעוֹלָם וָעֶד:\nוַאֲנַחְנוּ נְבָרֵךְ יָהּ מֵעַתָּה וְעַד עוֹלָם הַלְלוּיָהּ:","cond":[]},{"kind":"instruction","text":"חצי קדיש","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":[]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"header","text":"הוצאת ספר תורה","cond":["taanit"]},{"kind":"instruction","text":"הוצאת ספר תורה","cond":["taanit"]},{"kind":"text","text":"וַיְהִי בִּנְסֹעַ הָאָרֹן, וַיֹּאמֶר מֹשֶׁה: קוּמָה יהוה וְיָפֻצוּ אֹיְבֶיךָ וְיָנֻסוּ מְשַׂנְאֶיךָ מִפָּנֶיךָ:\nכִּי מִצִּיּוֹן תֵּצֵא תוֹרָה, וּדְבַר יהוה מִירוּשָׁלָיִם:\nבָּרוּךְ שֶׁנָּתַן תּוֹרָה לְעַמּוֹ יִשְׂרָאֵל בִּקְדֻשָּׁתוֹ.\n\nבְּרִיךְ שְׁמֵהּ דְּמָרֵא עָלְמָא, בְּרִיךְ כִּתְרָךְ וְאַתְרָךְ. יְהֵא רְעוּתָךְ עִם עַמָּךְ יִשְׂרָאֵל לְעָלַם, וּפֻרְקַן יְמִינָךְ אַחֲזֵי לְעַמָּךְ בְּבֵית מַקְדְּשָׁךְ, וּלְאַמְטוֹיֵי לָנָא מִטּוּב נְהוֹרָךְ וּלְקַבֵּל צְלוֹתָנָא בְּרַחֲמִין. יְהֵא רַעֲוָא קֳדָמָךְ דְּתוֹרִיךְ לָן חַיִּין בְּטִיבוּ, וְלֶהֱוֵי אֲנָא פְקִידָא בְּגוֹ צַדִּיקַיָּא, לְמִרְחַם עָלַי וּלְמִנְטַר יָתִי וְיַת כָּל דִּי לִי וְדִי לְעַמָּךְ יִשְׂרָאֵל. אַנְתְּ הוּא זָן לְכֹלָּא וּמְפַרְנֵס לְכֹלָּא, אַנְתְּ הוּא שַׁלִּיט עַל כֹּלָּא, אַנְתְּ הוּא דְשַׁלִּיט עַל מַלְכַיָּא, וּמַלְכוּתָא דִּילָךְ הִיא. אֲנָא עַבְדָּא דְקֻדְשָׁא בְּרִיךְ הוּא, דְּסָגֵדְנָא קַמֵּהּ וּמִקַּמֵּי דִּיקַר אוֹרַיְתֵהּ בְּכָל עִדָּן וְעִדָּן. לָא עַל אֱנָשׁ רָחִיצְנָא וְלָא עַל בַּר אֱלָהִין סָמִיכְנָא, אֶלָּא בֵּאלָהָא דִשְׁמַיָּא, דְּהוּא אֱלָהָא קְשׁוֹט, וְאוֹרַיְתֵהּ קְשׁוֹט, וּנְבִיאוֹהִי קְשׁוֹט, וּמַסְגֵּא לְמֶעְבַּד טַבְוָן וּקְשׁוֹט. בֵּהּ אֲנָא רָחִיץ, וְלִשְׁמֵהּ קַדִּישָׁא יַקִּירָא אֲנָא אֵמַר תֻּשְׁבְּחָן. יְהֵא רַעֲוָא קֳדָמָךְ דְּתִפְתַּח לִבָּאִי בְּאוֹרַיְתָא, וְתַשְׁלִים מִשְׁאֲלִין דְּלִבַּאי וְלִבָּא דְכָל עַמָּךְ יִשְׂרָאֵל לְטַב וּלְחַיִּין וְלִשְׁלָם.\n\nחזן - גַּדְּלוּ לַיהוה אִתִּי וּנְרוֹמְמָה שְׁמוֹ יַחְדָּו:\nקהל - לְךָ יהוה הַגְּדֻלָּה וְהַגְּבוּרָה וְהַתִּפְאֶרֶת וְהַנֵּצַח וְהַהוֹד, כִּי כֹל בַּשָּׁמַיִם וּבָאָרֶץ, לְךָ יהוה הַמַּמְלָכָה וְהַמִּתְנַשֵּׂא לְכֹל לְרֹאשׁ: רוֹמְמוּ יהוה אֱלֹהֵינוּ וְהִשְׁתַּחֲווּ לַהֲדֹם רַגְלָיו, קָדוֹשׁ הוּא: רוֹמְמוּ יהוה אֱלֹהֵינוּ וְהִשְׁתַּחֲווּ לְהַר קָדְשׁוֹ, כִּי קָדוֹשׁ יהוה אֱלֹהֵינוּ:\n\nאַב הָרַחֲמִים הוּא יְרַחֵם עַם עֲמוּסִים, וְיִזְכֹּר בְּרִית אֵיתָנִים, וְיַצִּיל נַפְשׁוֹתֵינוּ מִן הַשָּׁעוֹת הָרָעוֹת, וְיִגְעַר בְּיֵצֶר הָרָע מִן הַנְּשׂוּאִים, וְיָחֹן אוֹתָנוּ לִפְלֵטַת עוֹלָמִים, וִימַלֵּא מִשְׁאֲלוֹתֵינוּ בְּמִדָּה טוֹבָה יְשׁוּעָה וְרַחֲמִים.","cond":["taanit"]},{"kind":"instruction","text":"קריאת התורה","cond":["taanit"]},{"kind":"instruction","text":"לפני הקריאה מברך העולה:","cond":["taanit"]},{"kind":"instruction","text":"חזן:","cond":["taanit"]},{"kind":"text","text":"בָּרְכוּ אֶת יהוה הַמְבֹרָךְ.","cond":["taanit"]},{"kind":"instruction","text":"קהל וחזן:","cond":["taanit"]},{"kind":"text","text":"בָּרוּךְ יהוה הַמְבֹרָךְ לְעוֹלָם וָעֶד.","cond":["taanit"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר בָּחַר בָּנוּ מִכָּל הָעַמִּים וְנָתַן לָנוּ אֶת תּוֹרָתוֹ. בָּרוּךְ אַתָּה יהוה, נוֹתֵן הַתּוֹרָה.","cond":["taanit"]},{"kind":"instruction","text":"לאחר הקריאה מברך העולה:","cond":["taanit"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר נָתַן לָנוּ תּוֹרַת אֱמֶת וְחַיֵּי עוֹלָם נָטַע בְּתוֹכֵנוּ. בָּרוּךְ אַתָּה יהוה, נוֹתֵן הַתּוֹרָה.","cond":["taanit"]},{"kind":"header","text":"קריאת התורה","cond":["taanit"]},{"kind":"text","text":"וַיְחַל מֹשֶׁה אֶת פְּנֵי יהוה אֱלֹהָיו, וַיֹּאמֶר לָמָה יהוה יֶחֱרֶה אַפְּךָ בְּעַמֶּךָ אֲשֶׁר הוֹצֵאתָ מֵאֶרֶץ מִצְרַיִם בְּכֹחַ גָּדוֹל וּבְיָד חֲזָקָה: לָמָּה יֹאמְרוּ מִצְרַיִם לֵאמֹר בְּרָעָה הוֹצִיאָם לַהֲרֹג אֹתָם בֶּהָרִים וּלְכַלֹּתָם מֵעַל פְּנֵי הָאֲדָמָה, שׁוּב מֵחֲרוֹן אַפֶּךָ וְהִנָּחֵם עַל הָרָעָה לְעַמֶּךָ: זְכֹר לְאַבְרָהָם לְיִצְחָק וּלְיִשְׂרָאֵל עֲבָדֶיךָ אֲשֶׁר נִשְׁבַּעְתָּ לָהֶם בָּךְ, וַתְּדַבֵּר אֲלֵהֶם אַרְבֶּה אֶת זַרְעֲכֶם כְּכוֹכְבֵי הַשָּׁמָיִם, וְכָל הָאָרֶץ הַזֹּאת אֲשֶׁר אָמַרְתִּי אֶתֵּן לְזַרְעֲכֶם וְנָחֲלוּ לְעֹלָם: וַיִּנָּחֶם יהוה, עַל הָרָעָה אֲשֶׁר דִּבֶּר לַעֲשׂוֹת לְעַמּוֹ:","cond":["taanit"]},{"kind":"instruction","text":"עד כאן לכהן","cond":["taanit"]},{"kind":"text","text":"וַיֹּאמֶר יהוה אֶל מֹשֶׁה פְּסָל לְךָ שְׁנֵי לֻחֹת אֲבָנִים כָּרִאשֹׁנִים, וְכָתַבְתִּי עַל הַלֻּחֹת אֶת הַדְּבָרִים אֲשֶׁר הָיוּ עַל הַלֻּחֹת הָרִאשֹׁנִים אֲשֶׁר שִׁבַּרְתָּ: וֶהְיֵה נָכוֹן לַבֹּקֶר, וְעָלִיתָ בַבֹּקֶר אֶל הַר סִינַי וְנִצַּבְתָּ לִי שָׁם עַל רֹאשׁ הָהָר: וְאִישׁ לֹא יַעֲלֶה עִמָּךְ וְגַם אִישׁ אַל יֵרָא בְּכָל הָהָר, גַּם הַצֹּאן וְהַבָּקָר אַל יִרְעוּ אֶל מוּל הָהָר הַהוּא:","cond":["taanit"]},{"kind":"instruction","text":"עד כאן ללוי","cond":["taanit"]},{"kind":"text","text":"וַיִּפְסֹל שְׁנֵי לֻחֹת אֲבָנִים כָּרִאשֹׁנִים, וַיַּשְׁכֵּם מֹשֶׁה בַבֹּקֶר וַיַּעַל אֶל הַר סִינַי כַּאֲשֶׁר צִוָּה יהוה אֹתוֹ, וַיִּקַּח בְּיָדוֹ שְׁנֵי לֻחֹת אֲבָנִים: וַיֵּרֶד יהוה בֶּעָנָן וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם, יהוה: וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא, יהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה לֹא יְנַקֶּה, פֹּקֵד עֲוׂן אָבוֹת עַל בָּנִים וְעַל בְּנֵי בָנִים, עַל שִׁלֵּשִׁים וְעַל רִבֵּעִים: וַיְמַהֵר מֹשֶׁה, וַיִּקֹּד אַרְצָה וַיִּשְׁתָּחוּ: וַיֹּאמֶר אִם נָא מָצָאתִי חֵן בְּעֵינֶיךָ אֲדֹנָי יֵלֶךְ נָא אֲדֹנָי בְּקִרְבֵּנוּ, כִּי עַם קְשֵׁה עֹרֶף הוּא, וְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ: וַיֹּאמֶר הִנֵּה אָנֹכִי כֹּרֵת בְּרִית, נֶגֶד כָּל עַמְּךָ אֶעֱשֶׂה נִפְלָאֹת אֲשֶׁר לֹא נִבְרְאוּ בְכָל הָאָרֶץ וּבְכָל הַגּוֹיִם, וְרָאָה כָל הָעָם אֲשֶׁר אַתָּה בְקִרְבּוֹ אֶת מַעֲשֵׂה יהוה כִּי נוֹרָא הוּא, אֲשֶׁר אֲנִי עֹשֶׂה עִמָּךְ:","cond":["taanit"]},{"kind":"instruction","text":"עד כאן לישראל","cond":["taanit"]},{"kind":"instruction","text":"הגבהה וגלילה","cond":["taanit"]},{"kind":"text","text":"וְזֹאת הַתּוֹרָה אֲשֶׁר שָׂם מֹשֶׁה לִפְנֵי בְּנֵי יִשְׂרָאֵל עַל פִּי יהוה בְּיַד מֹשֶׁה.","cond":["taanit"]},{"kind":"header","text":"הפטרה","cond":["taanit"]},{"kind":"instruction","text":"הפטרה","cond":["taanit"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר בָּחַר בִּנְבִיאִים טוֹבִים, וְרָצָה בְדִבְרֵיהֶם הַנֶּאֱמָרִים בֶּאֱמֶת. בָּרוּךְ אַתָּה יהוה, הַבּוֹחֵר בַּתּוֹרָה וּבְמֹשֶׁה עַבְדּוֹ, וּבְיִשְׂרָאֵל עַמּוֹ, וּבִנְבִיאֵי הָאֱמֶת וְהַצֶּדֶק.","cond":["taanit"]},{"kind":"text","text":"דִּרְשׁוּ יהוה בְּהִמָּצְאוֹ, קְרָאֻהוּ בִּהְיוֹתוֹ קָרוֹב: יַעֲזֹב רָשָׁע דַּרְכּוֹ וְאִישׁ אָוֶן מַחְשְׁבֹתָיו, וְיָשֹׁב אֶל יהוה וִירַחֲמֵהוּ, וְאֶל אֱלֹהֵינוּ כִּי יַרְבֶּה לִסְלוֹחַ: כִּי לֹא מַחְשְׁבוֹתַי מַחְשְׁבוֹתֵיכֶם, וְלֹא דַרְכֵיכֶם דְּרָכָי, נְאֻם יהוה: כִּי גָבְהוּ שָׁמַיִם מֵאָרֶץ, כֵּן גָּבְהוּ דְרָכַי מִדַּרְכֵיכֶם וּמַחְשְׁבֹתַי מִמַּחְשְׁבֹתֵיכֶם: כִּי כַּאֲשֶׁר יֵרֵד הַגֶּשֶׁם וְהַשֶּׁלֶג מִן הַשָּׁמַיִם, וְשָׁמָּה לֹא יָשׁוּב, כִּי אִם הִרְוָה אֶת הָאָרֶץ וְהוֹלִידָהּ וְהִצְמִיחָהּ, וְנָתַן זֶרַע לַזֹּרֵעַ וְלֶחֶם לָאֹכֵל: כֵּן יִהְיֶה דְבָרִי אֲשֶׁר יֵצֵא מִפִּי, לֹא יָשׁוּב אֵלַי רֵיקָם, כִּי אִם עָשָׂה אֶת אֲשֶׁר חָפַצְתִּי וְהִצְלִיחַ אֲשֶׁר שְׁלַחְתִּיו: כִּי בְשִׂמְחָה תֵצֵאוּ וּבְשָׁלוֹם תּוּבָלוּן, הֶהָרִים וְהַגְּבָעוֹת יִפְצְחוּ לִפְנֵיכֶם רִנָּה וְכָל עֲצֵי הַשָּׂדֶה יִמְחֲאוּ כָף: תַּחַת הַנַּעֲצוּץ יַעֲלֶה בְרוֹשׁ, וְתַחַת הַסִּרְפַּד יַעֲלֶה הֲדַס, וְהָיָה לַיהוה לְשֵׁם, לְאוֹת עוֹלָם לֹא יִכָּרֵת: כֹּה אָמַר יהוה, שִׁמְרוּ מִשְׁפָּט וַעֲשׂוּ צְדָקָה, כִּי קְרוֹבָה יְשׁוּעָתִי לָבוֹא וְצִדְקָתִי לְהִגָּלוֹת: אַשְׁרֵי אֱנוֹשׁ יַעֲשֶׂה זֹּאת וּבֶן אָדָם יַחֲזִיק בָּהּ, שֹׁמֵר שַׁבָּת מֵחַלְּלוֹ וְשֹׁמֵר יָדוֹ מֵעֲשׂוֹת כָּל רָע: וְאַל יֹאמַר בֶּן הַנֵּכָר הַנִּלְוָה אֶל יהוה לֵאמֹר הַבְדֵּל יַבְדִּילַנִי יהוה מֵעַל עַמּוֹ, וְאַל יֹאמַר הַסָּרִיס הֵן אֲנִי עֵץ יָבֵשׁ: כִּי כֹה אָמַר יהוה לַסָּרִיסִים אֲשֶׁר יִשְׁמְרוּ אֶת שַׁבְּתוֹתַי וּבָחֲרוּ בַּאֲשֶׁר חָפָצְתִּי וּמַחֲזִיקִים בִּבְרִיתִי: וְנָתַתִּי לָהֶם בְּבֵיתִי וּבְחוֹמֹתַי יָד וָשֵׁם, טוֹב מִבָּנִים וּמִבָּנוֹת, שֵׁם עוֹלָם אֶתֶּן לוֹ אֲשֶׁר לֹא יִכָּרֵת: וּבְנֵי הַנֵּכָר הַנִּלְוִים עַל יהוה לְשָׁרְתוֹ וּלְאַהֲבָה אֶת שֵׁם יהוה לִהְיוֹת לוֹ לַעֲבָדִים, כָּל שֹׁמֵר שַׁבָּת מֵחַלְּלוֹ וּמַחֲזִיקִים בִּבְרִיתִי: וַהֲבִיאוֹתִים אֶל הַר קָדְשִׁי וְשִׂמַּחְתִּים בְּבֵית תְּפִלָּתִי, עוֹלֹתֵיהֶם וְזִבְחֵיהֶם לְרָצוֹן עַל מִזְבְּחִי, כִּי בֵיתִי בֵּית תְּפִלָּה יִקָּרֵא לְכָל הָעַמִּים: נְאֻם אֲדֹנָי יֱהֹוִה מְקַבֵּץ נִדְחֵי יִשְׂרָאֵל, עוֹד אֲקַבֵּץ עָלָיו לְנִקְבָּצָיו:","cond":["taanit"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, צוּר כָּל הָעוֹלָמִים, צַדִּיק בְּכָל הַדּוֹרוֹת, הָאֵל הַנֶּאֱמָן הָאוֹמֵר וְעוֹשֶׂה, הַמְדַבֵּר וּמְקַיֵּם שֶׁכָּל דְּבָרָיו אֱמֶת וָצֶדֶק. נֶאֱמָן אַתָּה הוּא יהוה אֱלֹהֵינוּ וְנֶאֱמָנִים דְּבָרֶיךָ, וְדָבָר אֶחָד מִדְּבָרֶיךָ אָחוֹר לֹא יָשׁוּב רֵיקָם, כִּי אֵל מֶלֶךְ נֶאֱמָן וְרַחֲמָן אָתָּה. בָּרוּךְ אַתָּה יהוה, הָאֵל הַנֶּאֱמָן בְּכָל דְּבָרָיו.\n\nרַחֵם עַל צִיּוֹן כִּי הִיא בֵּית חַיֵּינוּ, וְלַעֲלוּבַת נֶפֶשׁ תּוֹשִׁיעַ בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יהוה, מְשמֵּחַ צִיּוֹן בְּבָנֶיהָ.\n\nשַׂמְּחֵנוּ יהוה אֱלֹהֵינוּ בְּאֵלִיָּהוּ הַנָּבִיא עַבְדֶּךָ, וּבְמַלְכוּת בֵּית דָּוִד מְשִׁיחֶךָ, בִּמְהֵרָה יָבוֹא וְיָגֵל לִבֵּנוּ, עַל כִּסְאוֹ לֹא יֵשֵׁב זָר וְלֹא יִנְחֲלוּ עוֹד אֲחֵרִים אֶת כְּבוֹדוֹ, כִּי בְשֵׁם קָדְשְׁךָ נִשְׁבַּעְתָּ לּוֹ שֶׁלֹּא יִכְבֶּה נֵרוֹ לְעוֹלָם וָעֶד. בָּרוּךְ אַתָּה יהוה, מָגֵן דָּוִד.","cond":["taanit"]},{"kind":"header","text":"הכנסת ספר תורה","cond":["taanit"]},{"kind":"instruction","text":"הכנסת ספר תורה","cond":["taanit"]},{"kind":"text","text":"יְהַלְלוּ אֶת שֵׁם יהוה, כִּי נִשְׂגָּב שְׁמוֹ לְבַדּוֹ.\nוהקהל אומרים - הוֹדוֹ עַל אֶרֶץ וְשָׁמָיִם: וַיָּרֶם קֶרֶן לְעַמּוֹ, תְּהִלָּה לְכָל חֲסִידָיו, לִבְנֵי יִשְׂרָאֵל עַם קְרוֹבוֹ, הַלְלוּיָהּ:\n\nלְדָוִד מִזְמוֹר, לַיהוה הָאָרֶץ וּמְלוֹאָהּ, תֵּבֵל וְיֹשְׁבֵי בָהּ: כִּי הוּא עַל יַמִּים יְסָדָהּ, וְעַל נְהָרוֹת יְכוֹנְנֶהָ: מִי יַעֲלֶה בְהַר יהוה, וּמִי יָקוּם בִּמְקוֹם קָדְשׁוֹ: נְקִי כַפַּיִם וּבַר לֵבָב, אֲשֶׁר לֹא נָשָׂא לַשָּׁוְא נַפְשִׁי וְלֹא נִשְׁבַּע לְמִרְמָה: יִשָּׂא בְרָכָה מֵאֵת יהוה, וּצְדָקָה מֵאֱלֹהֵי יִשְׁעוֹ: זֶה דּוֹר דֹּרְשָׁיו, מְבַקְשֵׁי פָנֶיךָ יַעֲקֹב סֶלָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וְהִנָּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבוֹא מֶלֶךְ הַכָּבוֹד: מִי זֶה מֶלֶךְ הַכָּבוֹד, יהוה עִזּוּז וְגִבּוֹר, יהוה גִּבּוֹר מִלְחָמָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבֹא מֶלֶךְ הַכָּבוֹד: מִי הוּא זֶה מֶלֶךְ הַכָּבוֹד, יהוה צְבָאוֹת הוּא מֶלֶךְ הַכָּבוֹד סֶלָה:","cond":["taanit"]},{"kind":"instruction","text":"כשמכניסים את הספר אומרים","cond":["taanit"]},{"kind":"text","text":"וּבְנֻחֹה יֹאמַר: שׁוּבָה יהוה רִבְבוֹת אַלְפֵי יִשְׂרָאֵל: קוּמָה יהוה לִמְנוּחָתֶךָ, אַתָּה וַאֲרוֹן עֻזֶּךָ: כֹּהֲנֶיךָ יִלְבְּשׁוּ צֶדֶק, וַחֲסִידֶיךָ יְרַנֵּנוּ: בַּעֲבוּר דָּוִד עַבְדֶּךָ אַל תָּשֵׁב פְּנֵי מְשִׁיחֶךָ: כִּי לֶקַח טוֹב נָתַתִּי לָכֶם, תּוֹרָתִי אַל תַּעֲזֹבוּ: עֵץ חַיִּים הִיא לַמַּחֲזִיקִים בָּהּ, וְתֹמְכֶיהָ מְאֻשָּׁר: דְּרָכֶיהָ דַרְכֵי נֹעַם וְכָל נְתִיבוֹתֶיהָ שָׁלוֹם: הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם:","cond":["taanit"]},{"kind":"instruction","text":"חצי קדיש","cond":["taanit"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":["taanit"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["taanit","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["taanit","ayt"]},{"kind":"header","text":"עמידה","cond":[]},{"kind":"instruction","text":"תפילת העמידה","cond":[]},{"kind":"text","text":"כִּי שֵׁם יהוה אֶקְרָא, הָבוּ גֹדֶל לֵאלֹהֵינוּ:\nאֲדֹנָי, שְׂפָתַי תִּפְתָּח, וּפִי יַגִּיד תְּהִלָּתֶךָ:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק, וֵאלֹהֵי יַעֲקֹב, הָאֵל הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, וְקוֹנֵה הַכֹּל, וְזוֹכֵר חַסְדֵי אָבוֹת, וּמֵבִיא גוֹאֵל לִבְנֵי בְנֵיהֶם לְמַעַן שְׁמוֹ בְּאַהֲבָה.","cond":[]},{"kind":"special","text":"זָכְרֵנוּ לְחַיִּים, מֶלֶךְ חָפֵץ בַּחַיִּים, וְכָתְבֵנוּ בְּסֵפֶר הַחַיִּים, לְמַעַנְךָ אֱלֹהִים חַיִּים.","cond":["ayt"]},{"kind":"text","text":"מֶלֶךְ עוֹזֵר וּמוֹשִׁיעַ וּמָגֵן. בָּרוּךְ אַתָּה יהוה, מָגֵן אַבְרָהָם.","cond":[]},{"kind":"text","text":"אַתָּה גִּבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֵּה מֵתִים אַתָּה רַב לְהוֹשִׁיעַ,","cond":[]},{"kind":"summer","text":"מוֹרִיד הַטָּל,","cond":["summerTal"]},{"kind":"winter","text":"מַשִּׁיב הָרוּחַ וּמוֹרִיד הַגֶּשֶׁם,","cond":["winterTal"]},{"kind":"text","text":"מְכַלְכֵּל חַיִּים בְּחֶסֶד, מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים, סוֹמֵךְ נוֹפְלִים, וְרוֹפֵא חוֹלִים וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמוּנָתוֹ לִישֵׁנֵי עָפָר. מִי כָמוֹךָ בַּעַל גְּבוּרוֹת וּמִי דּוֹמֶה לָךְ, מֶלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִיחַ יְשׁוּעָה.","cond":[]},{"kind":"special","text":"מִי כָמוֹךָ אַב הָרַחֲמִים, זוֹכֵר יְצוּרָיו לְחַיִּים בְּרַחֲמִים.","cond":["ayt"]},{"kind":"text","text":"וְנֶאֱמָן אַתָּה לְהַחֲיוֹת מֵתִים. בָּרוּךְ אַתָּה יהוה, מְחַיֵּה הַמֵּתִים.","cond":[]},{"kind":"text","text":"אַתָּה קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ וּקְדוֹשִׁים בְּכָל יוֹם יְהַלְלוּךָ סֶּלָה.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הָאֵל הַקָּדוֹשׁ.","cond":["noayt"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יהוה, הַמֶּלֶךְ הַקָּדוֹשׁ.","cond":["ayt"]},{"kind":"text","text":"אַתָּה חוֹנֵן לְאָדָם דַּעַת וּמְלַמֵּד לֶאֱנוֹשׁ בִּינָה.","cond":[]},{"kind":"text","text":"חָנֵּנוּ מֵאִתְּךָ דֵעָה בִּינָה וְהַשְׂכֵּל.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, חוֹנֵן הַדָּעַת.","cond":[]},{"kind":"text","text":"הֲשִׁיבֵנוּ אָבִינוּ לְתוֹרָתֶךָ, וְקָרְבֵנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶך, וְהַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ. בָּרוּךְ אַתָּה יהוה, הָרוֹצֶה בִּתְשׁוּבָה.","cond":[]},{"kind":"text","text":"סְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ, כִּי מוֹחֵל וְסוֹלֵחַ אָתָּה. בָּרוּךְ אַתָּה יהוה, חַנּוּן הַמַּרְבֶּה לִסְלֹחַ.","cond":[]},{"kind":"text","text":"רְאֵה בְעָנְיֵנוּ וְרִיבָה רִיבֵנוּ, וּגְאָלֵנוּ מְהֵרָה לְמַעַן שְׁמֶךָ, כִּי גוֹאֵל חָזָק אָתָּה. בָּרוּךְ אַתָּה יהוה, גּוֹאֵל יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"רְפָאֵנוּ יהוה וְנֵרָפֵא, הוֹשִׁיעֵנוּ וְנִוָּשֵׁעָה כִּי תְהִלָּתֵנוּ אָתָּה, וְהַעֲלֵה רְפוּאָה שְׁלֵמָה לְכָל מַכּוֹתֵינוּ.","cond":[]},{"kind":"special","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁתִּשְׁלַח מְהֵרָה רְפוּאָה שְׁלֵמָה מִן הַשָּׁמַיִם, רְפוּאַת הַנֶּפֶשׁ וּרְפוּאַת הַגּוּף לַחוֹלֶה (לנקבה: לַחוֹלָה, לרבים: לַחוֹלִים, לרבות: לַחוֹלוֹת):\n:=:=\nבְּתוֹךְ שְׁאָר חוֹלֵי יִשְׂרָאֵל.","cond":["doctor"]},{"kind":"text","text":"כִּי אֵל מֶלֶךְ רוֹפֵא נֶאֱמָן וְרַחֲמָן אָתָּה. בָּרוּךְ אַתָּה יהוה, רוֹפֵא חוֹלֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"בָּרֵך עָלֵינוּ יהוה אֱלֹהֵינוּ אֶת הַשָּׁנָה הַזֹּאת וְאֶת כָּל מִינֵי תְבוּאָתָהּ לְטוֹבָה, וְתֵן","cond":[]},{"kind":"summer","text":"בְּרָכָה","cond":["summerBracha"]},{"kind":"winter","text":"טַל וּמָטָר לִבְרָכָה","cond":["winterBracha"]},{"kind":"text","text":"עַל פְּנֵי הָאֲדָמָה וְשַׂבְּעֵנוּ מִטּוּבָהּ, וּבָרֵךְ שְׁנָתֵנוּ כַּשָּׁנִים הַטּוֹבוֹת. בָּרוּךְ אַתָּה יהוה, מְבָרֵךְ הַשָּׁנִים.","cond":[]},{"kind":"text","text":"תְּקַע בְּשׁוֹפָר גָּדוֹל לְחֵרוּתֵנוּ, וְשָׂא נֵס לְקַבֵּץ גָּלֻיּוֹתֵינוּ, וְקַבְּצֵנוּ יַחַד מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ. בָּרוּךְ אַתָּה יהוה, מְקַבֵּץ נִדְחֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"הָשִׁיבָה שׁוֹפְטֵינוּ כְּבָרִאשׁוֹנָה וְיוֹעֲצֵינוּ כְּבַתְּחִלָּה, וְהָסֵר מִמֶּנּוּ יָגוֹן וַאֲנָחָה, וּמְלֹךְ עָלֵינוּ אַתָּה יהוה לְבַדְּךָ בְּחֶסֶד וּבְרַחֲמִים, וְצַדְּקֵנוּ בַּמִּשְׁפָט.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, מֶלֶךְ אוֹהֵב צְדָקָה וּמִשְׁפָּט.","cond":["noayt"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יהוה, הַמֶּלֶךְ הַמִּשְׁפָּט.","cond":["ayt"]},{"kind":"text","text":"וְלַמַּלְשִׁינִים אַל תְּהִי תִקְוָה, וְכָל הָרִשְׁעָה כְּרֶגַע תֹּאבֵד, וְכָל אוֹיְבֵי עַמְּךָ מְהֵרָה יִכָּרֵתוּ, וְהַזֵּדִים מְהֵרָה תְעַקֵּר וּתְשַׁבֵּר וּתְמַגֵּר וְתַכְנִיעַ בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יהוה, שׁוֹבֵר אוֹיְבִים וּמַכְנִיעַ זֵדִים.","cond":[]},{"kind":"text","text":"עַל הַצַּדִּיקִים וְעַל הַחֲסִידִים, וְעַל זִקְנֵי עַמְּךָ בֵּית יִשְׂרָאֵל, וְעַל פְּלֵיטַת סוֹפרֵיהֶם, וְעַל גֵּרֵי הַצֶּדֶק וְעָלֵינוּ, יֶהֱמוּ רַחֲמֶיךָ יהוה אֱלֹהֵינוּ, וְתֵן שָׂכָר טוֹב לְכָל הַבּוֹטְחִים בְּשִׁמְךָ בֶּאֱמֶת, וְשִׂים חֶלְקֵנוּ עִמָּהֶם לְעוֹלָם וְלֹא נֵבוֹשׁ כִּי בְךָ בָטָחְנוּ. בָּרוּךְ אַתָּה יהוה, מִשְׁעָן וּמִבְטָח לַצַּדִּיקִים.","cond":[]},{"kind":"text","text":"וְלִירוּשָׁלַיִם עִירְךָ בְּרַחֲמִים תָּשׁוּב וְתִשְׁכֹּן בְּתוֹכָהּ כַּאֲשֶׁר דִּבַּרְתָּ, וּבְנֵה אוֹתָהּ בְּקָרוֹב בְּיָמֵינוּ בִּנְיָן עוֹלָם, וְכִסֵּא דָוִד מְהֵרָה לְתוֹכָהּ תָּכִין.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, בּוֹנֵה יְרוּשָׁלָיִם.","cond":["noTishaaBeav"]},{"kind":"special","text":"נַחֵם יהוה אֱלֹהֵינוּ אֶת אֲבֵלֵי צִיּוֹן וְאֶת אֲבֵלֵי יְרוּשָלַיִם וְאֶת הָעִיר הָאֲבֵלָה וְהַחֲרֵבָה וְהַבְּזוּיָה וְהַשּׁוֹמְמָה. הָאֲבֵלָה מִבְּלִי בָנֶיהָ וְהַחֲרֵבָה מִמְּעוֹנוֹתֶיהָ, וְהַבְּזוּיָה מִכְּבוֹדָהּ, וְהַשּׁוֹמְמָה מֵאֵין יוֹשֵׁב. וְהִיא יוֹשֶׁבֶת וְראשָׁהּ חָפוּי כְּאִשָּׁה עֲקָרָה שֶׁלֹּא יָלָדָה. וַיְבַלְּעוּהָ לִגְיוֹנוֹת, וַיִּירָשׁוּהָ עוֹבְדֵי פְסִילִים, וַיָּטִילוּ אֶת עַמְּךָ יִשְׂרָאֵל לֶחָרֶב, וַיַּהַרְגוּ בְזָדוֹן חֲסִידֵי עֶלְיוֹן. עַל כֵּן צִיּוֹן בְּמַר תִּבְכֶּה, וִירוּשָׁלַיִם תִּתֵּן קוֹלָהּ. לִבִּי לִבִּי עַל חַלְלֵיהֶם, מֵעַי מֵעַי עַל חַלְלֵיהֶם, כִּי אַתָּה יהוה בָּאֵשׁ הִצַּתָּהּ, וּבָאֵשׁ אַתָּה עָתִיד לִבְנוֹתָהּ. כָּאָמוּר: וַאֲנִי אֶהְיֶה לָּהּ, נְאֻם יהוה, חוֹמַת אֵשׁ סָבִיב וּלְכָבוֹד אֶהְיֶה בְתוֹכָהּ:\nבָּרוּךְ אַתָּה יהוה, מְנַחֵם צִיּוֹן וּבוֹנֵה יְרוּשָׁלָיִם.","cond":["tishaaBeav"]},{"kind":"text","text":"אֶת צֶמַח דָּוִד עַבְדְּךָ מְהֵרָה תַצְמִיחַ, וְקַרְנוֹ תָּרוּם בִּישׁוּעָתֶךָ, כִּי לִישׁוּעָתְךָ קִוִּינוּ כָּל הַיּוֹם. בָּרוּךְ אַתָּה יהוה, מַצְמִיחַ קֶרֶן יְשׁוּעָה.","cond":[]},{"kind":"text","text":"שְׁמַע קוֹלֵנוּ יהוה אֱלֹהֵינוּ, חוּס וְרַחֵם עָלֵינוּ, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ, כִּי אֵל שׁוֹמֵעַ תְּפִלּוֹת וְתַחֲנוּנִים אָתָּה, וּמִלְּפָנֶיךָ מַלְכֵּנוּ, רֵיקָם אַל תְּשִׁיבֵנוּ.","cond":[]},{"kind":"instruction","text":"בתענית צבור יחיד אומר קודם כי אתה שומע:","cond":["taanit"]},{"kind":"special","text":"עֲנֵנוּ יהוה עֲנֵנוּ בְּיוֹם צוֹם תַּעֲנִיתֵנוּ, כִּי בְצָרָה גְדוֹלָה אֲנָחְנוּ. אַל תֵּפֶן אֶל רִשְׁעֵנוּ, וְאַל תַּסְתֵּר פָּנֶיךָ מִמֶּנּוּ, וְאַל תִּתְעַלַּם מִתְּחִנָּתֵנוּ. הֱיֵה נָא קָרוֹב לְשַׁוְעָתֵנוּ, יְהִי נָא חַסְדְּךָ לְנַחֲמֵנוּ, טֶרֶם נִקְרָא אֵלֶיךָ עֲנֵנוּ, כַּדָּבָר שֶׁנֶּאֱמַר: וְהָיָה טֶרֶם יִקְרָאוּ וַאֲנִי אֶעֱנֶה, עוֹד הֵם מְדַבְּרִים וַאֲנִי אֶשְׁמָע: כִּי אַתָּה יהוה הָעוֹנֶה בְּעֵת צָרָה, פּוֹדֶה וּמַצִּיל בְּכָל עֵת צָרָה וְצוּקָה.","cond":["taanit"]},{"kind":"special","text":"וַעֲנֵנוּ בּוֹרֵא עוֹלָם בְּמִדַּת הָרַחֲמִים, בּוֹחֵר בְּעַמּוֹ יִשְׂרָאֵל לְהוֹדִיעַ גָדְלוֹ וְהַדְרַת כְּבוֹדוֹ, שׁוֹמֵעַ תְּפִלָּה תֵּן טַל וּמָטָר עַל פְּנֵי הָאֲדָמָה, וְתַשְׂבִּיעַ אֶת הָעוֹלָם כֻּלּוֹ מִטּוּבֶךָ, וּמַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ וּמֵעֹשֶׁר מַתְּנַת יָדֶךָ, שְׁמוֹר וְהַצֵּל שָׁנָה זוֹ מִכָּל דָּבָר רָע, וּמִכָּל מִינִי מַשְׁחִית, וּמִכָּל מִינֵי פֻּרְעָנֻיּוֹת, וַעֲשֵׂה לָהּ תִּקְוָה וְאַחֲרִית שָׁלוֹם, חוּס וְרַחֵם עָלֵינוּ וְעַל כָּל תְּבוּאָתֵנוּ וּפֵרוֹתֵינוּ, וּבָרְכֵנוּ בְּגִשְׁמֵי בְרָכָה וְנִזְכֶּה לְחַיִּים וָשֹׂבַע וְשָׁלוֹם, כַּשָּׁנִים הַטּוֹבוֹת, וְהָסֵר מִמֶּנּוּ דֶּבֶר וְחֶרֶב וְרָעָב, וְחַיָּה רָעָה וּשְׁבִי וּבִזָּה, וְיֵצֶר הָרָע וָחֳלָיִם רָעִים וְקָשִׁים, וּמְאוֹרָעוֹת רָעִים וְקָשִׁים, וּגְזֹר עָלֵינוּ גְּזֵרוֹת טוֹבוֹת מִלְּפָנֶיךָ, וְיִגֹּלוּ רָחֲמֶיךָ עַל מִדּוֹתֶיךָ, וְתִתְנַהֵג עִם בָּנֶיךָ בְּמִדַּת הָרַחֲמִים, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ.","cond":["vaanenu"]},{"kind":"text","text":"כִּי אַתָּה שׁוֹמֵעַ תְּפִלַּת עַמְּךָ יִשְׂרָאֵל בְּרַחֲמִים. בָּרוּךְ אַתָּה יהוה, שׁוֹמֵעַ תְּפִלָּה.","cond":[]},{"kind":"text","text":"רְצֵה יהוה אֱלֹהֵינוּ בְּעַמְּךָ יִשְׂרָאֵל וּבִתְפִלָּתָם, וְהָשֵׁב אֶת הָעֲבוֹדָה לִדְבִיר בֵּיתֶךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם, בְּאַהֲבָה תְקַבֵּל בְּרָצוֹן. וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּךָ.","cond":[]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וּפִקְדוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךָ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים, לְחַיִּים וּלְשָׁלוֹם בְּיוֹם","cond":["rh"]},{"kind":"special","text":"רֹאשׁ הַחֹדֶשׁ הַזֶּה.","cond":["rh"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["rh"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וּפִקְדוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךָ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים, לְחַיִּים וּלְשָׁלוֹם בְּיוֹם","cond":["sucot"]},{"kind":"special","text":"חַג הַסֻּכּוֹת הַזֶּה.","cond":["sucot"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["sucot"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וּפִקְדוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךָ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים, לְחַיִּים וּלְשָׁלוֹם בְּיוֹם","cond":["pesach"]},{"kind":"special","text":"חַג הַמַּצּוֹת הַזֶּה.","cond":["pesach"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["pesach"]},{"kind":"text","text":"וְתֶחֱזֶינָה עֵינֵינוּ בְּשׁוּבְךָ לְצִיּוֹן בְּרַחֲמִים. בָּרוּךְ אַתָּה יהוה, הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן.","cond":[]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שָׁאַתָּה הוּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ לְעוֹלָם וָעֶד. צוּר חַיֵּינוּ, מָגֵן יִשְׁעֵנוּ אַתָּה הוּא לְדוֹר וָדוֹר. נוֹדֶה לְּךָ וּנְסַפֵּר תְּהִלָּתֶךָ עַל חַיֵּינוּ הַמְּסוּרִים בְּיָדֶךָ, וְעַל נִשְׁמוֹתֵינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּיךָ שֶׁבְּכָל יוֹם עִמָּנוּ, וְעַל נִפְלְאוֹתֶיךָ וְטוֹבוֹתֶיךָ שֶׁבְּכָל עֵת, עֶרֶב וָבֹקֶר וְצָהֳרָיִם. הַטּוֹב כִּי לֹא כָלוּ רַחֲמֶיךָ, וְהַמְרַחֵם כִּי לֹא תַמּוּ חֲסָדֶיךָ. מֵעוֹלָם קִוִּינוּ לָךְ.","cond":[]},{"kind":"special","text":"עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מַתִּתְיָהוּ בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְהַשְׁכִּיחָם תּוֹרָתֶךָ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנֶךָ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּטְמֵאִים בְּיַד טְהוֹרִים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, וּלְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמֶךָ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כֵּן בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ לְהוֹדוֹת וּלְהַלֵּל לְשִׁמְךָ הַגָּדוֹל.","cond":["chanuka"]},{"kind":"special","text":"עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים, מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ, וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ, וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְּרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ (, וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה).","cond":["purim"]},{"kind":"text","text":"וְעַל כֻּלָּם יִתְבָּרַךְ וְיִתְרוֹמַם שִׁמְךָ מַלְכֵּנוּ תָּמִיד לְעוֹלָם וָעֶד.","cond":[]},{"kind":"special","text":"וּכְתֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶךָ.","cond":["ayt"]},{"kind":"text","text":"וְכֹל הַחַיִּים יוֹדוּךָ סֶּלָה, וִיהַלְלוּ אֶת שִׁמְךָ בֶּאֱמֶת, הָאֵל יְשׁוּעָתֵנוּ וְעֶזְרָתֵנוּ סֶלָה. בָּרוּך אַתָּה יהוה, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת.","cond":[]},{"kind":"special","text":"שִׂים שָׁלוֹם טוֹבָה וּבְרָכָה, חֵן וָחֶסֶד וְרַחֲמִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל עַמֶּךָ, בָּרְכֵנוּ אָבִינוּ כֻּלָּנוּ כְּאֶחָד בְּאוֹר פָּנֶיךָ, כִּי בְאוֹר פָּנֶיךָ נָתַתָּ לָּנוּ יהוה אֱלֹהֵינוּ תּוֹרַת חַיִּים וְאַהֲבַת חֶסֶד, וּצְדָקָה וּבְרָכָה וְרַחֲמִים וְחַיִּים וְשָׁלוֹם, וְטוֹב בְּעֵינֶיךָ לְבָרֵךְ אֶת עַמְּךָ יִשְׂרָאֵל בְּכָל עֵת וּבְכָל שָׁעָה בִּשְׁלוֹמֶךָ.","cond":["taanit"]},{"kind":"text","text":"שָׁלוֹם רָב עַל יִשְׂרָאֵל עַמְּךָ תָּשִׂים לְעוֹלָם, כִּי אַתָּה הוּא מֶלֶךְ אָדוֹן לְכָל הַשָּלוֹם, וְטוֹב בְּעֵינֶיךָ לְבָרֵךְ אֶת עַמְּךָ יִשְׂרָאֵל בְּכָל עֵת וּבְכָל שָׁעָה בִּשְׁלוֹמֶךָ.","cond":["noTaanit"]},{"kind":"special","text":"בְּסֵפֶר חַיִּים, בְּרָכָה וְשָׁלוֹם, וּפַרְנָסָה טוֹבָה, נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ, אֲנַחְנוּ וְכָל עַמְּךָ בֵּית יִשְׂרָאֵל, לְחַיִּים טוֹבִים וּלְשָׁלוֹם.","cond":["ayt"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הַמְבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם.","cond":[]},{"kind":"text","text":"יִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:","cond":[]},{"kind":"header","text":"וידוי לעיו\"כ","cond":["kipur"]},{"kind":"instruction","text":"סדר וידוי לערב יום הכיפורים","cond":["kipur"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, תָּבוֹא לְפָנֶיךָ תְּפִלָּתֵנוּ וְאַל תִּתְעַלַּם מִתְּחִנָּתֵנוּ, שֶׁאֵין אֲנַחְנוּ עַזֵּי פָנִים וּקְשֵׁי עֹרֶף לוֹמַר לְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ צַדִּיקִים אֲנַחְנוּ וְלֹא חָטָאנוּ, אֲבָל אֲנַחְנוּ וַאֲבוֹתֵינוּ חָטָאנוּ.\nאָשַׁמְנוּ, בָּגַדְנוּ, גָּזַלְנוּ, דִּבַּרְנוּ דֹפִי. הֶעֱוִינוּ, וְהִרְשַׁעְנוּ, זַדְנוּ, חָמַסְנוּ, טָפַלְנוּ שֶׁקֶר. יָעַצְנוּ רָע, כִּזַּבְנוּ, לַצְנוּ, מָרַדְנוּ, נִאַצְנוּ, סָרַרְנוּ, עָוִינוּ, פָּשַׁעְנוּ, צָרַרְנוּ, קִשִּׁינוּ עֹרֶף. רָשַׁעְנוּ, שִׁחַתְנוּ, תִּעַבְנוּ, תָּעִינוּ, תִּעְתַּעְנוּ.\nסַרְנוּ מִמִּצְוׂתֶיךָ וּמִמִּשְׁפָּטֶיךָ הַטּוֹבִים וְלֹא שָׁוָה-לָנוּ. וְאַתָּה צַדִּיק עַל כָּל הַבָּא עָלֵינוּ, כִּי אֱמֶת עָשִׂיתָ, וַאֲנַחְנוּ הִרְשָׁעְנוּ:\nמַה נֹּאמַר לְפָנֶיךָ יוֹשֵׁב מָרוֹם, וּמַה נְּסַפֵּר לְפָנֶיךָ שׁוֹכֵן שְׁחָקִים, הֲלֹא כָּל הַנִּסְתָּרוֹת וְהַנִּגְלוֹת אַתָּה יוֹדֵעַ.\n\nאַתָּה יוֹדֵעַ רָזֵי עוֹלָם וְתַעֲלוּמוֹת סִתְרֵי כָל חָי. אַתָּה חוֹפֵשׂ כָּל חַדְרֵי בָטֶן וּבוֹחֵן כְּלָיוֹת וָלֵב. אֵין דָּבָר נֶעְלָם מִמֶּךָּ, וְאֵין נִסְתָּר מִנֶּגֶד עֵינֶיךָ.\nוּבְכֵן יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּסְלַח לָנוּ עַל כָּל חַטֹּאתֵינוּ, וְתִמְחַל לָנוּ עַל כָּל עֲוׂנוֹתֵינוּ, וּתְכַפֵּר לָנוּ עַל כָּל פְּשָׁעֵינוּ:\n\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּאֹנֶס וּבְרָצוֹן,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּאִמּוּץ הַלֵּב.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּבְלִי דָעַת,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּבִטּוּי שְׂפָתָיִם.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּגִלּוּי עֲרָיוֹת,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בַּגָּלוּי וּבַסָּתֶר.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּדַעַת וּבְמִרְמָה,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּדִבּוּר פֶּה.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּהוֹנָאַת רֵעַ,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּהִרְהוּר הַלֵּב.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּוְעִידַת זְנוּת,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּוִדּוּי פֶּה.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּזִלְזוּל הוֹרִים וּמוֹרִים,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּזָדוֹן וּבִשְׁגָגָה.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּחֹזֶק יָד,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּחִלּוּל הַשֵּׁם.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּטֻמְאַת שְׂפָתָיִם,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּטִפְּשׁוּת פֶּה.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּיֵצֶר הָרָע,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּיוֹדְעִים וּבְלֹא יוֹדְעִים.","cond":["kipur"]},{"kind":"special","text":"וְעַל כֻּלָּם, אֱלוֹהַּ סְלִיחוֹת, סְלַח לָנוּ, מְחַל לָנוּ, כַּפֶּר לָנוּ.","cond":["kipur"]},{"kind":"text","text":"עַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּכַחַשׁ וּבְכָזָב,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּכַפַּת שֹׁחַד.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּלָצוֹן,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּלָשׁוֹן הָרָע.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּמַשָּׂא וּבְמַתָּן,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּמַאֲכָל וּבְמִשְׁתֶּה.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּנֶשֶׁךְ וּבְמַרְבִּית,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּנְטִיַּת גָּרוֹן.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּשִׂיחַ שִׂפְתוֹתֵינוּ,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּשִׂקּוּר עָיִן.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּעֵינַיִם רָמוֹת,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּעַזּוּת מֶצַח.","cond":["kipur"]},{"kind":"special","text":"וְעַל כֻּלָּם, אֱלוֹהַּ סְלִיחוֹת, סְלַח לָנוּ, מְחַל לָנוּ, כַּפֶּר לָנוּ.","cond":["kipur"]},{"kind":"text","text":"עַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּפְרִיקַת עֹל,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּפְלִילוּת.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּצְדִיַּת רֵעַ,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּצָרוּת עָיִן.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּקַלּוּת רֹאשׁ,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּקַשְׁיוּת עֹרֶף.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּרִיצַת רַגְלַיִם לְהָרַע,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּרְכִילוּת.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּשְׁבוּעַת שָׁוְא,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּשִׂנְאַת חִנָּם.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּתְשׂוּמֶת יָד,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּתִמְהוֹן לֵבָב.","cond":["kipur"]},{"kind":"special","text":"וְעַל כֻּלָּם, אֱלוֹהַּ סְלִיחוֹת, סְלַח לָנוּ, מְחַל לָנוּ, כַּפֶּר לָנוּ.","cond":["kipur"]},{"kind":"text","text":"וְעַל חֲטָאִים שֶׁאָנוּ חַיָּבִים עֲלֵיהֶם עוֹלָה,\nוְעַל חֲטָאִים שֶׁאָנוּ חַיָּבִים עֲלֵיהֶם חַטָּאת,\nוְעַל חֲטָאִים שֶׁאָנוּ חַיָּבִים עֲלֵיהֶם קָרְבָּן עוֹלֶה וְיוֹרֵד,\nוְעַל חֲטָאִים שֶׁאָנוּ חַיָּבִים עֲלֵיהֶם אָשָׁם וַדַּאי וְתָלוּי,\nוְעַל חֲטָאִים שֶׁאָנוּ חַיָּבִים עֲלֵיהֶם מַכַּת מַרְדוּת,\nוְעַל חֲטָאִים שֶׁאָנוּ חַיָּבִים עֲלֵיהֶם מַלְקוּת אַרְבָּעִים,\nוְעַל חֲטָאִים שֶׁאָנוּ חַיָּבִים עֲלֵיהֶם מִיתָה בִּידֵי שָׁמָיִם,\nוְעַל חֲטָאִים שֶׁאָנוּ חַיָּבִים עֲלֵיהֶם כָּרֵת וַעֲרִירִי,\nוְעַל חֲטָאִים שֶׁאָנוּ חַיָּבִים עֲלֵיהֶם אַרְבַּע מִיתוֹת בֵּית דִּין: סְקִילָה, שְׂרֵפָה, הֶרֶג, וְחֶנֶק,\nעַל מִצְוַת עֲשֵׂה וְעַל מִצְוַת לֹא תַעֲשֶׂה, בֵּין שֶׁיֵּשׁ בָּהּ קוּם עֲשֵׂה וּבֵין שֶׁאֵין בָּהּ קוּם עֲשֵׂה, אֶת הַגְּלוּיִם לָנוּ וְאֶת שֶׁאֵינָם גְּלוּיִם לָנוּ: אֶת הַגְּלוּיִם לָנוּ כְּבָר אֲמַרְנוּם לְפָנֶיךָ וְהוֹדִינוּ לְךָ עֲלֵיהֶם, וְאֶת שֶׁאֵינָם גְּלוּיִם לָנוּ, לְפָנֶיךָ הֵם גְּלוּיִם וִידוּעִים, כַּדָּבָר שֶׁנֶּאֱמַר: הַנִּסְתָּרֹת לַיהוה אֱלֹהֵינוּ, וְהַנִּגְלֹת לָנוּ וּלְבָנֵינוּ עַד עוֹלָם, לַעֲשׂוֹת אֶת כָּל דִּבְרֵי הַתּוֹרָה הַזֹּאת: כִּי אַתָּה סָלְחָן לְיִשְׂרָאֵל וּמָחֳלָן לְשִׁבְטֵי יְשֻׁרוּן בְּכָל דּוֹר וָדוֹר, וּמִבַּלְעָדֶיךָ אֵין לָנוּ מֶלֶךְ מוֹחֵל וְסוֹלֵחַ.\n\nאֱלֹהַי, עַד שֶׁלֹּא נוֹצַרְתִּי אֵינִי כְדַאי, וְעַכְשָׁיו שֶׁנּוֹצַרְתִּי כְּאִלּוּ לֹא נוֹצַרְתִּי. עָפָר אֲנִי בְּחַיַּי, קַל וָחֹמֶר בְּמִיתָתִי. הֲרֵי אֲנִי לְפָנֶיךָ כִּכְלִי מָלֵא בוּשָׁה וּכְלִמָּה. יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁלֹּא אֶחֱטָא עוֹד, וּמַה שֶּׁחָטָאתִי לְפָנֶיךָ מְחֹק בְּרַחֲמֶיךָ הָרַבִּים, אֲבָל לֹא עַל יְדֵי יִסּוּרִים וָחֳלָיִים רָעִים.","cond":["kipur"]},{"kind":"text","text":"אֱלֹהַי, נְצֹר לְשׁוֹנִי מֵרָע וּשְׂפָתַי מִדַּבֵּר מִרְמָה, וְלִמְקַלְלַי נַפְשִׁי תִדֹּם, וְנַפְשִׁי כֶּעָפָר לַכֹּל תִּהְיֶה. פְּתַח לִבִּי בּתוֹרָתֶךָ, וּבְמִצְוׂתֶיךָ תִּרְדֹף נַפְשִׁי. וְכָל הַחוֹשְׁבִים עָלַי רָעָה, מְהֵרָה הָפֵר עֲצָתָם וְקַלְקֵל מַחֲשַׁבְתָּם. עֲשֵׂה לְמַעַן שְׁמֶךָ, עֲשֵׂה לְמַעַן יְמִינֶךָ, עֲשֵׂה לְמַעַן קְדֻשָּׁתֶךָ, עֲשֵׂה לְמַעַן תּוֹרָתֶךָ. לְמַעַן יֵחָלְצוּן יְדִידֶיךָ הוֹשִׁיעָה יְמִינְךָ וַעֲנֵנִי:\nיִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:","cond":[]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁיִּבָּנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵינוּ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתֶךָ, וְשָׁם נַעֲבָדְךָ בְּיִרְאָה כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמוֹנִיּוֹת. וְעָרְבָה לַיהוה מִנְחַת יְהוּדָה וִירוּשָׁלָיִם כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמֹנִיּוֹת:","cond":[]},{"kind":"header","text":"חזרת הש\"ץ","cond":[]},{"kind":"instruction","text":"חזרת הש\"ץ","cond":[]},{"kind":"text","text":"כִּי שֵׁם יהוה אֶקְרָא, הָבוּ גֹדֶל לֵאלֹהֵינוּ:\nאֲדֹנָי, שְׂפָתַי תִּפְתָּח, וּפִי יַגִּיד תְּהִלָּתֶךָ:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק, וֵאלֹהֵי יַעֲקֹב, הָאֵל הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, וְקוֹנֵה הַכֹּל, וְזוֹכֵר חַסְדֵי אָבוֹת, וּמֵבִיא גוֹאֵל לִבְנֵי בְנֵיהֶם לְמַעַן שְׁמוֹ בְּאַהֲבָה.","cond":[]},{"kind":"special","text":"זָכְרֵנוּ לְחַיִּים, מֶלֶךְ חָפֵץ בַּחַיִּים, וְכָתְבֵנוּ בְּסֵפֶר הַחַיִּים, לְמַעַנְךָ אֱלֹהִים חַיִּים.","cond":["ayt"]},{"kind":"text","text":"מֶלֶךְ עוֹזֵר וּמוֹשִׁיעַ וּמָגֵן. בָּרוּךְ אַתָּה יהוה, מָגֵן אַבְרָהָם.","cond":[]},{"kind":"text","text":"אַתָּה גִּבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֵּה מֵתִים אַתָּה רַב לְהוֹשִׁיעַ,","cond":[]},{"kind":"summer","text":"מוֹרִיד הַטָּל,","cond":["summerTal"]},{"kind":"winter","text":"מַשִּׁיב הָרוּחַ וּמוֹרִיד הַגֶּשֶׁם,","cond":["winterTal"]},{"kind":"text","text":"מְכַלְכֵּל חַיִּים בְּחֶסֶד, מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים, סוֹמֵךְ נוֹפְלִים, וְרוֹפֵא חוֹלִים וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמוּנָתוֹ לִישֵׁנֵי עָפָר. מִי כָמוֹךָ בַּעַל גְּבוּרוֹת וּמִי דּוֹמֶה לָךְ, מֶלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִיחַ יְשׁוּעָה.","cond":[]},{"kind":"special","text":"מִי כָמוֹךָ אַב הָרַחֲמִים, זוֹכֵר יְצוּרָיו לְחַיִּים בְּרַחֲמִים.","cond":["ayt"]},{"kind":"text","text":"וְנֶאֱמָן אַתָּה לְהַחֲיוֹת מֵתִים. בָּרוּךְ אַתָּה יהוה, מְחַיֵּה הַמֵּתִים.","cond":[]},{"kind":"header","text":"קדושה","cond":[]},{"kind":"instruction","text":"קדושה בחזרת הש\"ץ:","cond":[]},{"kind":"text","text":"נְקַדֵּשׁ אֶת שִׁמְךָ בָּעוֹלָם כְּשֵׁם שֶׁמַּקְדִּישִׁים אוֹתוֹ בִּשְׁמֵי מָרוֹם, כַּכָּתוּב עַל יַד נְבִיאֶךָ:\nוְקָרָא זֶה אֶל זֶה וְאָמַר:\nקו\"ח: קָדוֹשׁ, קָדוֹשׁ, קָדוֹשׁ יהוה צְבָאוֹת, מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ:\nחזן: לְעֻמָּתָם בָּרוּךְ יֹאמֵרוּ:\nקו\"ח: בָּרוּךְ כְּבוֹד יהוה מִמְּקוֹמוֹ:\nחזן: וּבְדִבְרֵי קָדְשְׁךָ כָּתוּב לֵאמֹר:\nקו\"ח: יִמְלֹך יהוה לְעוֹלָם, אֱלֹהַיִך צִיּוֹן לְדֹר וָדֹר, הַלְלוּיָהּ:\n\nלְדוֹר וָדוֹר נַגִּיד גָּדְלֶךָ וּלְנֵצַח נְצָחִים קְדֻשָּׁתְךָ נַקְדִּישׁ, וְשִׁבְחֲךָ אֱלֹהֵינוּ מִפִּינוּ לֹא יָמוּשׁ לְעוֹלָם וָעֵד, כִּי אֵל מֶלֶךְ גָּדוֹל וְקָדוֹשׁ אָתָּה.","cond":[]},{"kind":"special","text":"בָּרוּךְ אַתָּה יהוה, הַמֶּלֶךְ הַקָּדוֹשׁ.","cond":["ayt"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הָאֵל הַקָּדוֹשׁ.","cond":["noayt"]},{"kind":"text","text":"אַתָּה חוֹנֵן לְאָדָם דַּעַת וּמְלַמֵּד לֶאֱנוֹשׁ בִּינָה.","cond":[]},{"kind":"text","text":"חָנֵּנוּ מֵאִתְּךָ דֵעָה בִּינָה וְהַשְׂכֵּל.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, חוֹנֵן הַדָּעַת.","cond":[]},{"kind":"text","text":"הֲשִׁיבֵנוּ אָבִינוּ לְתוֹרָתֶךָ, וְקָרְבֵנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶך, וְהַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ. בָּרוּךְ אַתָּה יהוה, הָרוֹצֶה בִּתְשׁוּבָה.","cond":[]},{"kind":"text","text":"סְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ, כִּי מוֹחֵל וְסוֹלֵחַ אָתָּה. בָּרוּךְ אַתָּה יהוה, חַנּוּן הַמַּרְבֶּה לִסְלֹחַ.","cond":[]},{"kind":"text","text":"רְאֵה בְעָנְיֵנוּ וְרִיבָה רִיבֵנוּ, וּגְאָלֵנוּ מְהֵרָה לְמַעַן שְׁמֶךָ, כִּי גוֹאֵל חָזָק אָתָּה. בָּרוּךְ אַתָּה יהוה, גּוֹאֵל יִשְׂרָאֵל.","cond":[]},{"kind":"instruction","text":"בתענית צבור החזן אומר:","cond":["taanit"]},{"kind":"special","text":"עֲנֵנוּ יהוה עֲנֵנוּ בְּיוֹם צוֹם תַּעֲנִיתֵנוּ, כִּי בְצָרָה גְדוֹלָה אֲנָחְנוּ. אַל תֵּפֶן אֶל רִשְׁעֵנוּ, וְאַל תַּסְתֵּר פָּנֶיךָ מִמֶּנּוּ, וְאַל תִּתְעַלַּם מִתְּחִנָּתֵנוּ. הֱיֵה נָא קָרוֹב לְשַׁוְעָתֵנוּ, יְהִי נָא חַסְדְּךָ לְנַחֲמֵנוּ, טֶרֶם נִקְרָא אֵלֶיךָ עֲנֵנוּ, כַּדָּבָר שֶׁנֶּאֱמַר: וְהָיָה טֶרֶם יִקְרָאוּ וַאֲנִי אֶעֱנֶה, עוֹד הֵם מְדַבְּרִים וַאֲנִי אֶשְׁמָע: כִּי אַתָּה יהוה הָעוֹנֶה בְּעֵת צָרָה, פּוֹדֶה וּמַצִּיל בְּכָל עֵת צָרָה וְצוּקָה. בָּרוּךְ אַתָּה יהוה, הָעוֹנֶה בְּעֵת צָרָה.","cond":["taanit"]},{"kind":"text","text":"רְפָאֵנוּ יהוה וְנֵרָפֵא, הוֹשִׁיעֵנוּ וְנִוָּשֵׁעָה כִּי תְהִלָּתֵנוּ אָתָּה, וְהַעֲלֵה רְפוּאָה שְׁלֵמָה לְכָל מַכּוֹתֵינוּ, כִּי אֵל מֶלֶךְ רוֹפֵא נֶאֱמָן וְרַחֲמָן אָתָּה. בָּרוּךְ אַתָּה יהוה, רוֹפֵא חוֹלֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"בָּרֵך עָלֵינוּ יהוה אֱלֹהֵינוּ אֶת הַשָּׁנָה הַזֹּאת וְאֶת כָּל מִינֵי תְבוּאָתָהּ לְטוֹבָה, וְתֵן","cond":[]},{"kind":"summer","text":"בְּרָכָה","cond":["summerBracha"]},{"kind":"winter","text":"טַל וּמָטָר לִבְרָכָה","cond":["winterBracha"]},{"kind":"text","text":"עַל פְּנֵי הָאֲדָמָה וְשַׂבְּעֵנוּ מִטּוּבָהּ, וּבָרֵךְ שְׁנָתֵנוּ כַּשָּׁנִים הַטּוֹבוֹת. בָּרוּךְ אַתָּה יהוה, מְבָרֵךְ הַשָּׁנִים.","cond":[]},{"kind":"text","text":"תְּקַע בְּשׁוֹפָר גָּדוֹל לְחֵרוּתֵנוּ, וְשָׂא נֵס לְקַבֵּץ גָּלֻיּוֹתֵינוּ, וְקַבְּצֵנוּ יַחַד מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ. בָּרוּךְ אַתָּה יהוה, מְקַבֵּץ נִדְחֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"הָשִׁיבָה שׁוֹפְטֵינוּ כְּבָרִאשׁוֹנָה וְיוֹעֲצֵינוּ כְּבַתְּחִלָּה, וְהָסֵר מִמֶּנּוּ יָגוֹן וַאֲנָחָה, וּמְלֹךְ עָלֵינוּ אַתָּה יהוה לְבַדְּךָ בְּחֶסֶד וּבְרַחֲמִים, וְצַדְּקֵנוּ בַּמִּשְׁפָט.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, מֶלֶךְ אוֹהֵב צְדָקָה וּמִשְׁפָּט.","cond":["noayt"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יהוה, הַמֶּלֶךְ הַמִּשְׁפָּט.","cond":["ayt"]},{"kind":"text","text":"וְלַמַּלְשִׁינִים אַל תְּהִי תִקְוָה, וְכָל הָרִשְׁעָה כְּרֶגַע תֹּאבֵד, וְכָל אוֹיְבֵי עַמְּךָ מְהֵרָה יִכָּרֵתוּ, וְהַזֵּדִים מְהֵרָה תְעַקֵּר וּתְשַׁבֵּר וּתְמַגֵּר וְתַכְנִיעַ בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יהוה, שׁוֹבֵר אוֹיְבִים וּמַכְנִיעַ זֵדִים.","cond":[]},{"kind":"text","text":"עַל הַצַּדִּיקִים וְעַל הַחֲסִידִים, וְעַל זִקְנֵי עַמְּךָ בֵּית יִשְׂרָאֵל, וְעַל פְּלֵיטַת סוֹפרֵיהֶם, וְעַל גֵּרֵי הַצֶּדֶק וְעָלֵינוּ, יֶהֱמוּ רַחֲמֶיךָ יהוה אֱלֹהֵינוּ, וְתֵן שָׂכָר טוֹב לְכָל הַבּוֹטְחִים בְּשִׁמְךָ בֶּאֱמֶת, וְשִׂים חֶלְקֵנוּ עִמָּהֶם לְעוֹלָם וְלֹא נֵבוֹשׁ כִּי בְךָ בָטָחְנוּ. בָּרוּךְ אַתָּה יהוה, מִשְׁעָן וּמִבְטָח לַצַּדִּיקִים.","cond":[]},{"kind":"text","text":"וְלִירוּשָׁלַיִם עִירְךָ בְּרַחֲמִים תָּשׁוּב וְתִשְׁכֹּן בְּתוֹכָהּ כַּאֲשֶׁר דִּבַּרְתָּ, וּבְנֵה אוֹתָהּ בְּקָרוֹב בְּיָמֵינוּ בִּנְיָן עוֹלָם, וְכִסֵּא דָוִד מְהֵרָה לְתוֹכָהּ תָּכִין.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, בּוֹנֵה יְרוּשָׁלָיִם.","cond":["noTishaaBeav"]},{"kind":"special","text":"נַחֵם יהוה אֱלֹהֵינוּ אֶת אֲבֵלֵי צִיּוֹן וְאֶת אֲבֵלֵי יְרוּשָלַיִם וְאֶת הָעִיר הָאֲבֵלָה וְהַחֲרֵבָה וְהַבְּזוּיָה וְהַשּׁוֹמְמָה. הָאֲבֵלָה מִבְּלִי בָנֶיהָ וְהַחֲרֵבָה מִמְּעוֹנוֹתֶיהָ, וְהַבְּזוּיָה מִכְּבוֹדָהּ, וְהַשּׁוֹמְמָה מֵאֵין יוֹשֵׁב. וְהִיא יוֹשֶׁבֶת וְראשָׁהּ חָפוּי כְּאִשָּׁה עֲקָרָה שֶׁלֹּא יָלָדָה. וַיְבַלְּעוּהָ לִגְיוֹנוֹת, וַיִּירָשׁוּהָ עוֹבְדֵי פְסִילִים, וַיָּטִילוּ אֶת עַמְּךָ יִשְׂרָאֵל לֶחָרֶב, וַיַּהַרְגוּ בְזָדוֹן חֲסִידֵי עֶלְיוֹן. עַל כֵּן צִיּוֹן בְּמַר תִּבְכֶּה, וִירוּשָׁלַיִם תִּתֵּן קוֹלָהּ. לִבִּי לִבִּי עַל חַלְלֵיהֶם, מֵעַי מֵעַי עַל חַלְלֵיהֶם, כִּי אַתָּה יהוה בָּאֵשׁ הִצַּתָּהּ, וּבָאֵשׁ אַתָּה עָתִיד לִבְנוֹתָהּ. כָּאָמוּר: וַאֲנִי אֶהְיֶה לָּהּ, נְאֻם יהוה, חוֹמַת אֵשׁ סָבִיב וּלְכָבוֹד אֶהְיֶה בְתוֹכָהּ:\nבָּרוּךְ אַתָּה יהוה, מְנַחֵם צִיּוֹן וּבוֹנֵה יְרוּשָׁלָיִם.","cond":["tishaaBeav"]},{"kind":"text","text":"אֶת צֶמַח דָּוִד עַבְדְּךָ מְהֵרָה תַצְמִיחַ, וְקַרְנוֹ תָּרוּם בִּישׁוּעָתֶךָ, כִּי לִישׁוּעָתְךָ קִוִּינוּ כָּל הַיּוֹם. בָּרוּךְ אַתָּה יהוה, מַצְמִיחַ קֶרֶן יְשׁוּעָה.","cond":[]},{"kind":"text","text":"שְׁמַע קוֹלֵנוּ יהוה אֱלֹהֵינוּ, חוּס וְרַחֵם עָלֵינוּ, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ, כִּי אֵל שׁוֹמֵעַ תְּפִלּוֹת וְתַחֲנוּנִים אָתָּה, וּמִלְּפָנֶיךָ מַלְכֵּנוּ, רֵיקָם אַל תְּשִׁיבֵנוּ.","cond":[]},{"kind":"special","text":"וַעֲנֵנוּ בּוֹרֵא עוֹלָם בְּמִדַּת הָרַחֲמִים, בּוֹחֵר בְּעַמּוֹ יִשְׂרָאֵל לְהוֹדִיעַ גָדְלוֹ וְהַדְרַת כְּבוֹדוֹ, שׁוֹמֵעַ תְּפִלָּה תֵּן טַל וּמָטָר עַל פְּנֵי הָאֲדָמָה, וְתַשְׂבִּיעַ אֶת הָעוֹלָם כֻּלּוֹ מִטּוּבֶךָ, וּמַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ וּמֵעֹשֶׁר מַתְּנַת יָדֶךָ, שְׁמוֹר וְהַצֵּל שָׁנָה זוֹ מִכָּל דָּבָר רָע, וּמִכָּל מִינִי מַשְׁחִית, וּמִכָּל מִינֵי פֻּרְעָנֻיּוֹת, וַעֲשֵׂה לָהּ תִּקְוָה וְאַחֲרִית שָׁלוֹם, חוּס וְרַחֵם עָלֵינוּ וְעַל כָּל תְּבוּאָתֵנוּ וּפֵרוֹתֵינוּ, וּבָרְכֵנוּ בְּגִשְׁמֵי בְרָכָה וְנִזְכֶּה לְחַיִּים וָשֹׂבַע וְשָׁלוֹם, כַּשָּׁנִים הַטּוֹבוֹת, וְהָסֵר מִמֶּנּוּ דֶּבֶר וְחֶרֶב וְרָעָב, וְחַיָּה רָעָה וּשְׁבִי וּבִזָּה, וְיֵצֶר הָרָע וָחֳלָיִם רָעִים וְקָשִׁים, וּמְאוֹרָעוֹת רָעִים וְקָשִׁים, וּגְזֹר עָלֵינוּ גְּזֵרוֹת טוֹבוֹת מִלְּפָנֶיךָ, וְיִגֹּלוּ רָחֲמֶיךָ עַל מִדּוֹתֶיךָ, וְתִתְנַהֵג עִם בָּנֶיךָ בְּמִדַּת הָרַחֲמִים, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ.","cond":["vaanenu"]},{"kind":"text","text":"כִּי אַתָּה שׁוֹמֵעַ תְּפִלַּת עַמְּךָ יִשְׂרָאֵל בְּרַחֲמִים. בָּרוּךְ אַתָּה יהוה, שׁוֹמֵעַ תְּפִלָּה.","cond":[]},{"kind":"text","text":"רְצֵה יהוה אֱלֹהֵינוּ בְּעַמְּךָ יִשְׂרָאֵל וּבִתְפִלָּתָם, וְהָשֵׁב אֶת הָעֲבוֹדָה לִדְבִיר בֵּיתֶךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם, בְּאַהֲבָה תְקַבֵּל בְּרָצוֹן. וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּךָ.","cond":[]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וּפִקְדוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךָ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים, לְחַיִּים וּלְשָׁלוֹם בְּיוֹם","cond":["rh"]},{"kind":"special","text":"רֹאשׁ הַחֹדֶשׁ הַזֶּה.","cond":["rh"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["rh"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וּפִקְדוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךָ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים, לְחַיִּים וּלְשָׁלוֹם בְּיוֹם","cond":["sucot"]},{"kind":"special","text":"חַג הַסֻּכּוֹת הַזֶּה.","cond":["sucot"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["sucot"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וּפִקְדוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךָ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים, לְחַיִּים וּלְשָׁלוֹם בְּיוֹם","cond":["pesach"]},{"kind":"special","text":"חַג הַמַּצּוֹת הַזֶּה.","cond":["pesach"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["pesach"]},{"kind":"text","text":"וְתֶחֱזֶינָה עֵינֵינוּ בְּשׁוּבְךָ לְצִיּוֹן בְּרַחֲמִים. בָּרוּךְ אַתָּה יהוה, הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן.","cond":[]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שָׁאַתָּה הוּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ לְעוֹלָם וָעֶד. צוּר חַיֵּינוּ, מָגֵן יִשְׁעֵנוּ אַתָּה הוּא לְדוֹר וָדוֹר. נוֹדֶה לְּךָ וּנְסַפֵּר תְּהִלָּתֶךָ עַל חַיֵּינוּ הַמְּסוּרִים בְּיָדֶךָ, וְעַל נִשְׁמוֹתֵינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּיךָ שֶׁבְּכָל יוֹם עִמָּנוּ, וְעַל נִפְלְאוֹתֶיךָ וְטוֹבוֹתֶיךָ שֶׁבְּכָל עֵת, עֶרֶב וָבֹקֶר וְצָהֳרָיִם. הַטּוֹב כִּי לֹא כָלוּ רַחֲמֶיךָ, וְהַמְרַחֵם כִּי לֹא תַמּוּ חֲסָדֶיךָ. מֵעוֹלָם קִוִּינוּ לָךְ.","cond":[]},{"kind":"header","text":"מודים דרבנן","cond":[]},{"kind":"instruction","text":"מודים דרבנן:","cond":[]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שָׁאַתָּה הוּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי כָל בָּשָׂר, יוֹצְרֵנוּ יוֹצֵר בְּרֵאשִׁית. בְּרָכוֹת וְהוֹדָאוֹת לְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ, עַל שֶׁהֶחֱיִיתָנוּ וְקִיַּמְתָּנוּ. כֵּן תְּחַיֵּנוּ וּתְקַיְּמֵנוּ, וְתֶאֱסוֹף גָּלֻיּוֹתֵינוּ לְחַצְרוֹת קָדְשֶׁךָ, לִשְׁמוֹר חֻקֶּיךָ וְלַעֲשׂוֹת רְצוֹנֶךָ, וּלְעָבְדְּךָ בְּלֵבָב שָׁלֵם, עַל שֶׁאֲנַחְנוּ מוֹדִים לָךְ. בָּרוּךְ אֵל הַהוֹדָאוֹת.","cond":[]},{"kind":"special","text":"עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מַתִּתְיָהוּ בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְהַשְׁכִּיחָם תּוֹרָתֶךָ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנֶךָ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּטְמֵאִים בְּיַד טְהוֹרִים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, וּלְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמֶךָ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כֵּן בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ לְהוֹדוֹת וּלְהַלֵּל לְשִׁמְךָ הַגָּדוֹל.","cond":["chanuka"]},{"kind":"special","text":"עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים, מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ, וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ, וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְּרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ (, וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה).","cond":["purim"]},{"kind":"text","text":"וְעַל כֻּלָּם יִתְבָּרַךְ וְיִתְרוֹמַם שִׁמְךָ מַלְכֵּנוּ תָּמִיד לְעוֹלָם וָעֶד.","cond":[]},{"kind":"special","text":"וּכְתֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶךָ.","cond":["ayt"]},{"kind":"text","text":"וְכֹל הַחַיִּים יוֹדוּךָ סֶּלָה, וִיהַלְלוּ אֶת שִׁמְךָ בֶּאֱמֶת, הָאֵל יְשׁוּעָתֵנוּ וְעֶזְרָתֵנוּ סֶלָה. בָּרוּך אַתָּה יהוה, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת.","cond":[]},{"kind":"header","text":"ברכת כהנים","cond":["taanit"]},{"kind":"instruction","text":"ברכת כהנים לחזרת הש\"ץ:\n\nאם לא עלו כהנים לדוכן הש\"ץ אומר או\"א (נמצא בהמשך).\n\nאם עלו שני כהנים לדוכן קוראים להם - כֹּהֲנִים:\n\nהכהנים מברכים:","cond":["taanit"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בִּקְדֻשָּׁתוֹ שֶׁל אַהֲרֹן, וְצִוָּנוּ לְבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בְּאַהֲבָה.\n\nיְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ:\nיָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ:\nיִשָּׂא יהוה פָּנָיו אֵלֶיךָ וְיָשֵׂם לְךָ שָׁלוֹם:","cond":["taanit"]},{"kind":"instruction","text":"הקהל אומר:","cond":["taanit"]},{"kind":"text","text":"אַדִּיר בַּמָּרוֹם שׁוֹכֵן בִּגְבוּרָה, אַתָּה שָׁלוֹם וְשִׁמְךָ שָׁלוֹם. יְהִי רָצוֹן שֶׁתָּשִׂים עָלֵינוּ וְעַל כָּל עַמְּךָ בֵּית יִשְׂרָאֵל חַיִּים וּבְרָכָה לְמִשְׁמֶרֶת שָׁלוֹם.","cond":["taanit"]},{"kind":"instruction","text":"הכהנים אומרים","cond":["taanit"]},{"kind":"text","text":"רִבּוֹנוֹ שֶׁל עוֹלָם, עָשִׂינוּ מַה שֶּׁגָּזַרְתָּ עָלֵינוּ, אַף אַתָּה עֲשֵׂה עִמָּנוּ כְּמוֹ שֶׁהִבְטַחְתָּנוּ: הַשְׁקִיפָה מִמְּעוֹן קָדְשְׁךָ מִן הַשָּׁמַיִם, וּבָרֵךְ אֶת עַמְּךָ אֶת יִשְׂרָאֵל, וְאֵת הָאֲדָמָה אֲשֶׁר נָתַתָּה לָנוּ, כַּאֲשֶׁר נִשְׁבַּעְתָּ לַאֲבֹתֵינוּ, אֶרֶץ זָבַת חָלָב וּדְבָשׁ:","cond":["taanit"]},{"kind":"instruction","text":"אם לא עלו כהנים לדוכן הש\"ץ אומר:","cond":["taanit"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, בָּרְכֵנוּ בַּבְּרָכָה הַמְשֻׁלֶּשֶׁת בַּתּוֹרָה הַכְּתוּבָה עַל יְדֵי מֹשֶׁה עַבְדֶּךָ, הָאֲמוּרָה מִפִּי אַהֲרֹן וּבָנָיו כֹּהֲנִים עַם קְדוֹשֶׁךָ, כָּאָמוּר: יְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ: יָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ: יִשָּׂא יהוה פָּנָיו אֵלֶיךָ וְיָשֵׂם לְךָ שָׁלוֹם:","cond":["taanit"]},{"kind":"special","text":"שִׂים שָׁלוֹם טוֹבָה וּבְרָכָה, חֵן וָחֶסֶד וְרַחֲמִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל עַמֶּךָ, בָּרְכֵנוּ אָבִינוּ כֻּלָּנוּ כְּאֶחָד בְּאוֹר פָּנֶיךָ, כִּי בְאוֹר פָּנֶיךָ נָתַתָּ לָּנוּ יהוה אֱלֹהֵינוּ תּוֹרַת חַיִּים וְאַהֲבַת חֶסֶד, וּצְדָקָה וּבְרָכָה וְרַחֲמִים וְחַיִּים וְשָׁלוֹם, וְטוֹב בְּעֵינֶיךָ לְבָרֵךְ אֶת עַמְּךָ יִשְׂרָאֵל בְּכָל עֵת וּבְכָל שָׁעָה בִּשְׁלוֹמֶךָ.","cond":["taanit"]},{"kind":"text","text":"שָׁלוֹם רָב עַל יִשְׂרָאֵל עַמְּךָ תָּשִׂים לְעוֹלָם, כִּי אַתָּה הוּא מֶלֶךְ אָדוֹן לְכָל הַשָּלוֹם, וְטוֹב בְּעֵינֶיךָ לְבָרֵךְ אֶת עַמְּךָ יִשְׂרָאֵל בְּכָל עֵת וּבְכָל שָׁעָה בִּשְׁלוֹמֶךָ.","cond":["noTaanit"]},{"kind":"special","text":"בְּסֵפֶר חַיִּים, בְּרָכָה וְשָׁלוֹם, וּפַרְנָסָה טוֹבָה, נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ, אֲנַחְנוּ וְכָל עַמְּךָ בֵּית יִשְׂרָאֵל, לְחַיִּים טוֹבִים וּלְשָׁלוֹם.","cond":["ayt"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הַמְבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם.","cond":[]},{"kind":"text","text":"יִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:","cond":[]},{"kind":"header","text":"תחנון","cond":["minchaTachanun"]},{"kind":"instruction","text":"יש נוהגים שלא לומר תחנון היום, ובפרט בארץ ישראל שיכולים בקלות להגיע לירושלים לשמוח עימם בשמחת פורים דמוקפין.","cond":["minchaTachanun","purim_meshulash_tachanun_message"]},{"kind":"instruction","text":"בבית האבל אין אומרים תחנון ומדלגים לקדיש תתקבל.","cond":["minchaTachanun"]},{"kind":"header","text":"אבינו מלכנו","cond":["minchaTachanun","noGedalya"]},{"kind":"instruction","text":"אבינו מלכנו","cond":["minchaTachanun","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חָטָאנוּ לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, אֵין לָנוּ מֶלֶךְ אֶלָּא אָתָּה.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה עִמָּנוּ לְמַעַן שְׁמֶךָ.","cond":["minchaTachanun","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חַדֵּשׁ עָלֵינוּ שָׁנָה טוֹבָה.","cond":["minchaTachanun","noGedalya","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, בָּרֵךְ עָלֵינוּ שָׁנָה טוֹבָה.","cond":["minchaTachanun","noGedalya","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, בַּטֵּל מֵעָלֵינוּ כָּל גְּזֵרוֹת קָשׁוֹת.\nאָבִינוּ מַלְכֵּנוּ, בַּטֵּל מַחְשְׁבוֹת שׂוֹנְאֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, הָפֵר עֲצַת אוֹיְבֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה כָּל צַר וּמַשְׂטִין מֵעָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, סְתֹם פִּיּוֹת מַשְׂטִינֵינוּ וּמְקַטְרְגֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה דֶבֶר וְחֶרֶב וְרָעָב וּשְׁבִי וּמַשְׁחִית וְעָוׂן וּשְׁמַד מִבְּנֵי בְרִיתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, מְנַע מַגֵּפָה מִנַּחֲלָתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, סְלַח וּמְחַל לְכָל עֲוׂנוֹתֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, מְחֵה וְהַעֲבֵר פְּשָׁעֵינוּ וְחַטֹּאתֵינוּ מִנֶּגֶד עֵינֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, מְחֹק בְּרַחֲמֶיךָ הָרַבִּים כָּל שִׁטְרֵי חוֹבוֹתֵינוּ.","cond":["minchaTachanun","noGedalya"]},{"kind":"instruction","text":"מכאן אומרים בקול עם החזן","cond":["minchaTachanun","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, הַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, שְׁלַח רְפוּאָה שְׁלֵמָה לְחוֹלֵי עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, קְרַע רֹע גְּזַר דִּינֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ בְּזִכְרוֹן טוֹב לְפָנֶיךָ.","cond":["minchaTachanun","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר חַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר גְּאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר פַּרְנָסָה וְכַלְכָּלָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר זְכֻיּוֹת.\nאָבִינוּ מַלְכֵּנוּ, כָָּתְבֵנוּ בְּסֵפֶר סְלִיחָה וּמְחִילָה.","cond":["minchaTachanun","noGedalya","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לְחַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִגְאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לְפַרְנָסָה וְכַלְכָּלָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִזְכֻיּוֹת.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִסְלִיחָה וּמְחִילָה.","cond":["minchaTachanun","noGedalya","noGedalya"]},{"kind":"instruction","text":"עד כאן עם החזן","cond":["minchaTachanun","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, הַצְמַח לָנוּ יְשׁוּעָה בְּקָרוֹב.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן יִשְׂרָאֵל עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן מְשִׁיחֶךָ.\nאָבִינוּ מַלְכֵּנוּ, מַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, מַלֵּא אֲסָמֵינוּ שָׂבָע.\nאָבִינוּ מַלְכֵּנוּ, שְׁמַע קוֹלֵנוּ, חוּס וְרַחֵם עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, קַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, פְּתַח שַׁעֲרֵי שָׁמַיִם לִתְפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, זְכֹר כִּי עָפָר אֲנַחְנוּ.\nאָבִינוּ מַלְכֵּנוּ, נָא אַל תְּשִׁיבֵנוּ רֵיקָם מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, תְּהֵא הַשָּׁעָה הַזֹּאת שְׁעַת רַחֲמִים וְעֵת רָצוֹן מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, חֲמֹל עָלֵינוּ וְעַל עוֹלָלֵינוּ וְטַפֵּנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן הֲרוּגִים עַל שֶׁם קָדְשֶׁךָ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן טְבוּחִים עַל יִחוּדֶךָ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן בָּאֵי בָאֵשׁ וּבַמָּיִּם עַל קִדּוּשׁ שְׁמֶךָ.\nאָבִינוּ מַלְכֵּנוּ, נְקֹם לְעֵינֵינוּ נִקְמַת דַּם עֲבָדֶיךָ הַשָּׁפוּךְ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַנְךָ אִם לֹא לְמַעַנֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַנְךָ וְהוֹשִׁיעֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַן רַחֲמֶיךָ הָרַבִּים.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַן שִׁמְךָ הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא שֶׁנִּקְרָא עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, חָנֵּנוּ וַעֲנֵנוּ כִּי אֵין בָּנוּ מַעֲשִׂים, עֲשֵׂה עִמָּנוּ צְדָקָה וָחֶסֶד וְהוֹשִׁיעֵנוּ.","cond":["minchaTachanun","noGedalya"]},{"kind":"header","text":"אבינו מלכנו","cond":["minchaTachanun","ayt"]},{"kind":"instruction","text":"אבינו מלכנו","cond":["minchaTachanun","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חָטָאנוּ לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, אֵין לָנוּ מֶלֶךְ אֶלָּא אָתָּה.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה עִמָּנוּ לְמַעַן שְׁמֶךָ.","cond":["minchaTachanun","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חַדֵּשׁ עָלֵינוּ שָׁנָה טוֹבָה.","cond":["minchaTachanun","ayt","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, בָּרֵךְ עָלֵינוּ שָׁנָה טוֹבָה.","cond":["minchaTachanun","ayt","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, בַּטֵּל מֵעָלֵינוּ כָּל גְּזֵרוֹת קָשׁוֹת.\nאָבִינוּ מַלְכֵּנוּ, בַּטֵּל מַחְשְׁבוֹת שׂוֹנְאֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, הָפֵר עֲצַת אוֹיְבֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה כָּל צַר וּמַשְׂטִין מֵעָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, סְתֹם פִּיּוֹת מַשְׂטִינֵינוּ וּמְקַטְרְגֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה דֶבֶר וְחֶרֶב וְרָעָב וּשְׁבִי וּמַשְׁחִית וְעָוׂן וּשְׁמַד מִבְּנֵי בְרִיתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, מְנַע מַגֵּפָה מִנַּחֲלָתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, סְלַח וּמְחַל לְכָל עֲוׂנוֹתֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, מְחֵה וְהַעֲבֵר פְּשָׁעֵינוּ וְחַטֹּאתֵינוּ מִנֶּגֶד עֵינֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, מְחֹק בְּרַחֲמֶיךָ הָרַבִּים כָּל שִׁטְרֵי חוֹבוֹתֵינוּ.","cond":["minchaTachanun","ayt"]},{"kind":"instruction","text":"מכאן אומרים בקול עם החזן","cond":["minchaTachanun","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, הַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, שְׁלַח רְפוּאָה שְׁלֵמָה לְחוֹלֵי עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, קְרַע רֹע גְּזַר דִּינֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ בְּזִכְרוֹן טוֹב לְפָנֶיךָ.","cond":["minchaTachanun","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר חַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר גְּאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר פַּרְנָסָה וְכַלְכָּלָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר זְכֻיּוֹת.\nאָבִינוּ מַלְכֵּנוּ, כָָּתְבֵנוּ בְּסֵפֶר סְלִיחָה וּמְחִילָה.","cond":["minchaTachanun","ayt","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לְחַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִגְאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לְפַרְנָסָה וְכַלְכָּלָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִזְכֻיּוֹת.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִסְלִיחָה וּמְחִילָה.","cond":["minchaTachanun","ayt","noGedalya"]},{"kind":"instruction","text":"עד כאן עם החזן","cond":["minchaTachanun","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, הַצְמַח לָנוּ יְשׁוּעָה בְּקָרוֹב.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן יִשְׂרָאֵל עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן מְשִׁיחֶךָ.\nאָבִינוּ מַלְכֵּנוּ, מַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, מַלֵּא אֲסָמֵינוּ שָׂבָע.\nאָבִינוּ מַלְכֵּנוּ, שְׁמַע קוֹלֵנוּ, חוּס וְרַחֵם עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, קַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, פְּתַח שַׁעֲרֵי שָׁמַיִם לִתְפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, זְכֹר כִּי עָפָר אֲנַחְנוּ.\nאָבִינוּ מַלְכֵּנוּ, נָא אַל תְּשִׁיבֵנוּ רֵיקָם מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, תְּהֵא הַשָּׁעָה הַזֹּאת שְׁעַת רַחֲמִים וְעֵת רָצוֹן מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, חֲמֹל עָלֵינוּ וְעַל עוֹלָלֵינוּ וְטַפֵּנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן הֲרוּגִים עַל שֶׁם קָדְשֶׁךָ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן טְבוּחִים עַל יִחוּדֶךָ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן בָּאֵי בָאֵשׁ וּבַמָּיִּם עַל קִדּוּשׁ שְׁמֶךָ.\nאָבִינוּ מַלְכֵּנוּ, נְקֹם לְעֵינֵינוּ נִקְמַת דַּם עֲבָדֶיךָ הַשָּׁפוּךְ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַנְךָ אִם לֹא לְמַעַנֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַנְךָ וְהוֹשִׁיעֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַן רַחֲמֶיךָ הָרַבִּים.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַן שִׁמְךָ הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא שֶׁנִּקְרָא עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, חָנֵּנוּ וַעֲנֵנוּ כִּי אֵין בָּנוּ מַעֲשִׂים, עֲשֵׂה עִמָּנוּ צְדָקָה וָחֶסֶד וְהוֹשִׁיעֵנוּ.","cond":["minchaTachanun","ayt"]},{"kind":"instruction","text":"נפילת אפיים","cond":["minchaTachanun"]},{"kind":"text","text":"וַיֹּאמֶר דָּוִד אֶל גָּד, צַר לִי מְאֹד, נִפְּלָה נָּא בְיַד יהוה כִּי רַבִּים רַחֲמָיו, וּבְיַד אָדָם אַל אֶפֹּלָה:\n\nרַחוּם וְחַנּוּן חָטָאתִי לְפָנֶיך. יהוה מָלֵא רַחֲמִים, רַחֵם עָלַי וְקַבֵּל תַּחֲנוּנָי.\n\nיהוה, אַל בְּאַפְּךָ תוֹכִיחֵנִי וְאַל בַּחֲמָתְךָ תְיַסְּרֵנִי: חָנֵּנִי יהוה כִּי אֻמְלַל אָנִי, רְפָאֵנִי יהוה כִּי נִבְהֲלוּ עֲצָמָי: וְנַפְשִׁי נִבְהֲלָה מְאֹד, וְאַתָּה יהוה עַד מָתָי: שׁוּבָה יהוה חַלְּצָה נַפְשִׁי, הוֹשִׁיעֵנִי לְמַעַן חַסְדֶּךָ: כִּי אֵין בַּמָּוֶת זִכְרֶךָ, בִּשְׁאוֹל מִי יוֹדֶה לָּךְ: יָגַעְתִּי בְאַנְחָתִי, אַשְׂחֶה בְכָל לַיְלָה מִטָּתִי, בְּדִמְעָתִי עַרְשִׂי אַמְסֶה: עָשְׁשָׁה מִכַּעַס עֵינִי, עָתְקָה בְּכָל צוֹרְרָי: סוּרוּ מִמֶּנִּי כָּל פֹּעֲלֵי אָוֶן כִּי שָׁמַע יהוה קוֹל בִּכְיִי: שָׁמַע יהוה תְּחִנָּתִי, יהוה תְּפִלָּתִי יִקָּח: יֵבֹשׁוּ וְיִבָּהֲלוּ מְאֹד כָּל אֹיְבָי, יָשֻׁבוּ יֵבֹשׁוּ רָגַע:","cond":["minchaTachanun"]},{"kind":"instruction","text":"שומר ישראל","cond":["minchaTachanun"]},{"kind":"text","text":"שׁוֹמֵר יִשְׂרָאֵל, שְׁמֹר שְׁאֵרִית יִשְׂרָאֵל, וְאַל יֹאבַד יִשְׂרָאֵל, הָאוֹמְרִים שְׁמַע יִשְׂרָאֵל.\nשׁוֹמֵר גּוֹי אֶחָד, שְׁמֹר שְׁאֵרִית עַם אֶחָד, וְאַל יֹאבַד גּוֹי אֶחָד, הַמְיַחֲדִים שִׁמְךָ יהוה אֱלֹהֵינוּ יהוה אֶחָד.\nשׁוֹמֵר גּוֹי קָדוֹשׁ, שְׁמֹר שְׁאֵרִית עַם קָדוֹשׁ, וְאַל יֹאבַד גּוֹי קָדוֹשׁ, הַמְשַׁלְּשִׁים בְּשָׁלֹשׁ קְדֻשּׁוֹת לְקָדוֹשׁ.\n\nמִתְרַצֶּה בְּרַחֲמִים וּמִתְפַּיֵּס בְּתַחֲנוּנִים, הִתְרַצֶּה וְהִתְפַּיֵּס לְדוֹר עָנִי. כִּי אֵין עוֹזֵר.\nאָבִינוּ מַלְכֵּנוּ. חָנֵּנוּ וַעֲנֵנוּ, כִּי אֵין בָּנוּ מַעֲשִׂים, עֲשֵׂה עִמָּנוּ צְדָקָה וָחֶסֶד וְהוֹשִׁיעֵנוּ.\n\nוַאֲנַחְנוּ לֹא נֵדַע מַה נַּעֲשֶׂה, כִּי עָלֶיךָ עֵינֵינוּ: זְכֹר רַחֲמֶיךָ יהוה וַחֲסָדֶיךָ, כִּי מֵעוֹלָם הֵמָּה: יְהִי חַסְדְּךָ יהוה עָלֵינוּ, כַּאֲשֶׁר יִחַלְנוּ לָךְ: אַל תִּזְכָּר לָנוּ עֲוׂנוֹת רִאשׁוֹנִים, מַהֵר יְקַדְּמוּנוּ רַחֲמֶיךָ, כִּי דַלּוֹנוּ מְאֹד: חָנֵּנוּ יהוה חָנֵּנוּ, כִּי רַב שָׂבַעְנוּ בוּז: בְּרֹגֶז רַחֵם תִּזְכּוֹר: כִּי הוּא יָדַע יִצְרֵנוּ, זָכוּר כִּי עָפָר אֲנָחְנוּ: עָזְרֵנוּ אֱלֹהֵי יִשְׁעֵנוּ עַל דְּבַר כְּבוֹד שְׁמֶךָ, וְהַצִּילֵנוּ וְכַפֵּר עַל חַטֹּאתֵינוּ לְמַעַן שְׁמֶךָ:","cond":["minchaTachanun"]},{"kind":"instruction","text":"קדיש תתקבל","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":[]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"תִּתְקַבַּל צְלוֹתְהוֹן וּבָעוּתְהוֹן דְּכָל יִשְׂרָאֵל קֳדָם אֲבוּהוֹן דִּי בִשְׁמַיָּא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"header","text":"עלינו לשבח","cond":[]},{"kind":"text","text":"עָלֵינוּ לְשַׁבֵּחַ לַאֲדוֹן הַכֹּל, לָתֵת גְּדֻלָּה לְיוֹצֵר בְּרֵאשִׁית, שֶׁלֹּא עָשָׂנוּ כְּגוֹיֵי הָאֲרָצוֹת, וְלֹא שָׂמָנוּ כְּמִשְׁפְּחוֹת הָאֲדָמָה. שֶׁלֹּא שָׂם חֶלְקֵנוּ כָּהֶם, וְגוֹרָלֵנוּ כְּכָל-הֲמוֹנָם, שֶׁהֵם מִשְׁתַּחֲוִים לְהֶבֶל וָרִיק, וּמִתְפַּלְּלִים אֶל אֵל לֹא יוֹשִׁיעַ. וַאֲנַחְנוּ כּוֹרְעִים וּמִשְׁתַּחֲוִים וּמוֹדִים לִפְנֵי מֶלֶךְ מַלְכֵי הַמְּלָכִים הַקָּדוֹשׁ בָּרוּךְ הוּא, שֶׁהוּא נוֹטֶה שָׁמַיִם וְיוֹסֵד אָרֶץ, וּמוֹשַׁב יְקָרוֹ בַּשָּׁמַיִם מִמַּעַל, וּשְׁכִינַת עֻזּוֹ בְּגָבְהֵי מְרוֹמִים. הוּא אֱלֹהֵינוּ, אֵין עוֹד, אֱמֶת מַלְכֵּנוּ, אֶפֶס זוּלָתוֹ, כַּכָּתוּב בְּתוֹרָתוֹ: וְיָדַעְתָּ הַיּוֹם וַהֲשֵׁבֹתָ אֶל לְבָבֶךָ כִּי יהוה הוּא הָאֱלֹהִים בַּשָּׁמַיִם מִמַּעַל וְעַל הָאָרֶץ מִתָּחַת אֵין עוֹד:","cond":[]},{"kind":"text","text":"עַל כֵּן נְקַוֶּה לְךָ יהוה אֱלֹהֵינוּ, לִרְאוֹת מְהֵרָה בְּתִפְאֶרֶת עֻזֶּךָ, לְהַעֲבִיר גִּלּוּלִים מִן הָאָרֶץ, וְהָאֱלִילִים כָּרוֹת יִכָּרֵתוּן, לְתַקֵּן עוֹלָם בְּמַלְכוּת שַׁדַּי, וְכָל בְּנֵי בָשָׂר יִקְרְאוּ בִשְׁמֶךָ, לְהַפְנוֹת אֵלֶיךָ כָּל רִשְׁעֵי אָרֶץ. יַכִּירוּ וְיֵדְעוּ כָּל יוֹשְׁבֵי תֵבֵל, כִּי לְךָ תִכְרַע כָּל בֶּרֶךְ, תִּשָּׁבַע כָּל לָשׁוֹן. לְפָנֶיךָ יהוה אֱלֹהֵינוּ יִכְרְעוּ וְיִפֹּלוּ, וְלִכְבוֹד שִׁמְךָ יְקָר יִתֵּנוּ, וִיקַבְּלוּ כֻלָּם אֶת עֹל מַלְכוּתֶךָ, וְתִמְלֹךְ עֲלֵיהֶם מְהֵרָה לְעוֹלָם וָעֶד. כִּי הַמַּלְכוּת שֶׁלְּךָ הִיא, וּלְעוֹלְמֵי עַד תִּמְלֹךְ בְּכָבוֹד, כַּכָּתוּב בְּתוֹרָתֶךָ: יהוה יִמְלֹךְ לְעֹלָם וָעֶד: וְנֶאֱמַר: וְהָיָה יהוה לְמֶלֶךְ עַל כָּל הָאָרֶץ בַּיּוֹם הַהוּא יִהְיֶה יהוה אֶחָד וּשְׁמוֹ אֶחָד:","cond":[]},{"kind":"text","text":"אַל תִּירָא מִפַּחַד פִּתְאֹם וּמִשֹּׁאַת רְשָׁעִים כִּי תָבֹא: עֻצוּ עֵצָה וְתֻפָר, דַּבְּרוּ דָבָר וְלֹא יָקוּם, כִּי עִמָּנוּ אֵל: וְעַד זִקְנָה אֲנִי הוּא, וְעַד שֵׂיבָה אֲנִי אֶסְבֹּל אֲנִי עָשִׂיתִי וַאֲנִי אֶשָּׂא וַאֲנִי אֶסְבֹּל וַאֲמַלֵּט:","cond":[]},{"kind":"instruction","text":"קדיש יתום","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":[]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"header","text":"השלמת שחרית","cond":["tishaaBeav"]},{"kind":"header","text":"שיר של יום","cond":["tishaaBeav"]},{"kind":"instruction","text":"שיר של יום","cond":["tishaaBeav"]},{"kind":"text","text":"הַיּוֹם יוֹם רִאשׁוֹן בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["tishaaBeav","sun"]},{"kind":"text","text":"לְדָוִד מִזְמוֹר, לַיהוה הָאָרֶץ וּמְלוֹאָהּ, תֵּבֵל וְיֹשְׁבֵי בָהּ: כִּי הוּא עַל יַמִּים יְסָדָהּ, וְעַל נְהָרוֹת יְכוֹנְנֶהָ: מִי יַעֲלֶה בְהַר יהוה, וּמִי יָקוּם בִּמְקוֹם קָדְשׁוֹ: נְקִי כַפַּיִם וּבַר לֵבָב, אֲשֶׁר לֹא נָשָׂא לַשָּׁוְא נַפְשִׁי וְלֹא נִשְׁבַּע לְמִרְמָה: יִשָּׂא בְרָכָה מֵאֵת יהוה, וּצְדָקָה מֵאֱלֹהֵי יִשְׁעוֹ: זֶה דּוֹר דֹּרְשָׁיו, מְבַקְשֵׁי פָנֶיךָ יַעֲקֹב סֶלָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וְהִנָּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבוֹא מֶלֶךְ הַכָּבוֹד: מִי זֶה מֶלֶךְ הַכָּבוֹד, יהוה עִזּוּז וְגִבּוֹר, יהוה גִּבּוֹר מִלְחָמָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבֹא מֶלֶךְ הַכָּבוֹד: מִי הוּא זֶה מֶלֶךְ הַכָּבוֹד, יהוה צְבָאוֹת הוּא מֶלֶךְ הַכָּבוֹד סֶלָה:","cond":["tishaaBeav","sun"]},{"kind":"text","text":"הַיּוֹם יוֹם שֵׁנִי בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["tishaaBeav","mon"]},{"kind":"text","text":"שִׁיר מִזְמוֹר לִבְנֵי קֹרַח: גָּדוֹל יהוה וּמְהֻלָּל מְאֹד בְּעִיר אֱלֹהֵינוּ הַר קָדְשׁוֹ: יְפֵה נוֹף, מְשׂוֹשׂ כָּל הָאָרֶץ, הַר צִיּוֹן יַרְכְּתֵי צָפוֹן קִרְיַת מֶלֶךְ רָב: אֱלֹהִים בְּאַרְמְנוֹתֶיהָ נוֹדַע לְמִשְׂגָּב: כִּי הִנֵּה הַמְּלָכִים נוֹעֲדוּ עָבְרוּ יַחְדָּו: הֵמָּה רָאוּ כֵּן תָּמָהוּ, נִבְהֲלוּ נֶחְפָּזוּ: רְעָדָה אֲחָזָתַם שָׁם, חִיל כַּיּוֹלֵדָה: בְּרוּחַ קָדִים תְּשַׁבֵּר אֳנִיּוֹת תַּרְשִׁישׁ: כַּאֲשֶׁר שָׁמַעְנוּ כֵּן רָאִינוּ בְּעִיר יהוה צְבָאוֹת בְּעִיר אֱלֹהֵינוּ, אֱלֹהִים יְכוֹנְנֶהָ עַד עוֹלָם סֶלָה: דִּמִּינוּ אֱלֹהִים חַסְדֶּךָ בְּקֶרֶב הֵיכָלֶךָ: כְּשִׁמְךָ אֱלֹהִים כֵּן תְּהִלָּתְךָ עַל קַצְוֵי אֶרֶץ, צֶדֶק מָלְאָה יְמִינֶךָ: יִשְׂמַח הַר צִיּוֹן, תָּגֵלְנָה בְּנוֹת יְהוּדָה, לְמַעַן מִשְׁפָּטֶיךָ: סֹבּוּ צִיּוֹן וְהַקִּיפוּהָ, סִפְרוּ מִגְדָּלֶיהָ: שִׁיתוּ לִבְּכֶם לְחֵילָה, פַּסְּגוּ אַרְמְנוֹתֶיהָ, לְמַעַן תְּסַפְּרוּ לְדוֹר אַחֲרוֹן: כִּי זֶה אֱלֹהִים אֱלֹהֵינוּ עוֹלָם וָעֶד, הוּא יְנַהֲגֵנוּ עַל מוּת:","cond":["tishaaBeav","mon"]},{"kind":"text","text":"הַיּוֹם יוֹם שְׁלִישִׁי בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["tishaaBeav","tue"]},{"kind":"text","text":"מִזְמוֹר לְאָסָף, אֱלֹהִים נִצָּב בַּעֲדַת אֵל, בְּקֶרֶב אֱלֹהִים יִשְׁפֹּט: עַד מָתַי תִּשְׁפְּטוּ עָוֶל וּפְנֵי רְשָׁעִים תִּשְׂאוּ סֶלָה: שִׁפְטוּ דַל וְיָתוֹם, עָנִי וָרָשׁ הַצְדִּיקוּ: פַּלְּטוּ דַל וְאֶבְיוֹן, מִיַּד רְשָׁעִים הַצִּילוּ: לֹא יָדְעוּ וְלֹא יָבִינוּ, בַּחֲשֵׁכָה יִתְהַלָּכוּ, יִמּוֹטוּ כָּל מוֹסְדֵי אָרֶץ: אֲנִי אָמַרְתִּי אֱלֹהִים אַתֶּם וּבְנֵי עֶלְיוֹן כֻּלְּכֶם: אָכֵן כְּאָדָם תְּמוּתוּן וּכְאַחַד הַשָּׂרִים תִּפֹּלוּ: קוּמָה אֱלֹהִים שָׁפְטָה הָאָרֶץ, כִּי אַתָּה תִנְחַל בְּכָל הַגּוֹיִם:","cond":["tishaaBeav","tue"]},{"kind":"text","text":"הַיּוֹם יוֹם רְבִיעִי בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["tishaaBeav","wed"]},{"kind":"text","text":"אֵל נְקָמוֹת יהוה, אֵל נְקָמוֹת הוֹפִיעַ: הִנָּשֵׂא שֹׁפֵט הָאָרֶץ, הָשֵׁב גְּמוּל עַל גֵּאִים: עַד מָתַי רְשָׁעִים, יהוה, עַד מָתַי רְשָׁעִים יַעֲלֹזוּ: יַבִּיעוּ יְדַבְּרוּ עָתָק, יִתְאַמְּרוּ כָּל פֹעֲלֵי אָוֶן: עַמְּךָ יהוה יְדַכְּאוּ, וְנַחֲלָתְךָ יְעַנּוּ: אַלְמָנָה וְגֵר יַהֲרֹגוּ, וִיתוֹמִים יְרַצֵּחוּ: וַיֹּאמְרוּ לֹא יִרְאֶה יָהּ, וְלֹא יָבִין אֱלֹהֵי יַעֲקֹב: בִּינוּ בֹּעֲרִים בָּעָם, וּכְסִילִים מָתַי תַּשְׂכִּילוּ: הַנֹּטַע אֹזֶן הֲלֹא יִשְׁמָע, אִם יֹצֵר עַיִן הֲלֹא יַבִּיט: הֲיֹסֵר גּוֹיִם הֲלֹא יוֹכִיחַ, הַמְלַמֵּד אָדָם דָּעַת: יהוה יֹדֵעַ מַחְשְׁבוֹת אָדָם כִּי הֵמָּה הָבֶל: אַשְׁרֵי הַגֶּבֶר אֲשֶׁר תְּיַסְּרֶנּוּ יָּהּ, וּמִתּוֹרָתְךָ תְלַמְּדֶנּוּ: לְהַשְׁקִיט לוֹ מִימֵי רָע, עַד יִכָּרֶה לָרָשָׁע שָׁחַת: כִּי לֹא יִטֹּשׁ יהוה עַמּוֹ, וְנַחֲלָתוֹ לֹא יַעֲזֹב: כִּי עַד צֶדֶק יָשׁוּב מִשְׁפָּט, וְאַחֲרָיו כָּל יִשְׁרֵי לֵב: מִי יָקוּם לִי עִם מְרֵעִים, מִי יִתְיַצֵּב לִי עִם פֹּעֲלֵי אָוֶן: לוּלֵי יהוה עֶזְרָתָה לִּי, כִּמְעַט שָׁכְנָה דוּמָה נַפְשִׁי: אִם אָמַרְתִּי מָטָה רַגְלִי, חַסְדְּךָ יהוה יִסְעָדֵנִי: בְּרֹב שַׂרְעַפַּי בְּקִרְבִּי, תַּנְחוּמֶיךָ יְשַׁעַשְׁעוּ נַפְשִׁי: הַיְחָבְרְךָ כִּסֵּא הַוּוֹת, יֹצֵר עָמָל עֲלֵי חֹק: יָגוֹדּוּ עַל נֶפֶשׁ צַדִּיק, וְדָם נָקִי יַרְשִׁיעוּ: וַיְהִי יהוה לִי לְמִשְׂגָּב, וֵאלֹהַי לְצוּר מַחְסִי: וַיָּשֶׁב עֲלֵיהֶם אֶת אוֹנָם וּבְרָעָתָם יַצְמִיתֵם, יַצְמִיתֵם יהוה אֱלֹהֵינוּ:\nלְכוּ נְרַנְּנָה לַיהוה, נָרִיעָה לְצוּר יִשְׁעֵנוּ: נְקַדְּמָה פָנָיו בְּתוֹדָה, בִּזְמִרוֹת נָרִיעַ לוֹ: כִּי אֵל גָּדוֹל יהוה, וּמֶלֶךְ גָּדוֹל עַל כָּל אֱלֹהִים:","cond":["tishaaBeav","wed"]},{"kind":"text","text":"הַיּוֹם יוֹם חֲמִישִׁי בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["tishaaBeav","thu"]},{"kind":"text","text":"לַמְנַצֵּחַ עַל הַגִּתִּית לְאָסָף: הַרְנִינוּ לֵאלֹהִים עֻזֵּנוּ, הָרִיעוּ לֵאלֹהֵי יַעֲקֹב: שְׂאוּ זִמְרָה וּתְנוּ תֹף, כִּנּוֹר נָעִים עִם נָבֶל: תִּקְעוּ בַחֹדֶשׁ שׁוֹפָר, בַּכֵּסֶה לְיוֹם חַגֵּנוּ: כִּי חֹק לְיִשְׂרָאֵל הוּא, מִשְׁפָּט לֵאלֹהֵי יַעֲקֹב: עֵדוּת בִּיהוֹסֵף שָׂמוֹ בְּצֵאתוֹ עַל אֶרֶץ מִצְרָיִם, שְׂפַת לֹא יָדַעְתִּי אֶשְׁמָע: הֲסִירוֹתִי מִסֵּבֶל שִׁכְמוֹ, כַּפָּיו מִדּוּד תַּעֲבֹרְנָה: בַּצָּרָה קָרָאתָ וָאֲחַלְּצֶךָּ, אֶעֶנְךָ בְּסֵתֶר רַעַם, אֶבְחָנְךָ עַל מֵי מְרִיבָה סֶלָה: שְׁמַע עַמִּי וְאָעִידָה בָּךְ, יִשְׂרָאֵל אִם תִּשְׁמַע לִי: לֹא יִהְיֶה בְךָ אֵל זָר, וְלֹא תִשְׁתַּחֲוֶה לְאֵל נֵכָר: אָנֹכִי יהוה אֱלֹהֶיךָ הַמַּעַלְךָ מֵאֶרֶץ מִצְרָיִם, הַרְחֶב פִּיךָ וַאֲמַלְאֵהוּ: וְלֹא שָׁמַע עַמִּי לְקוֹלִי, וְיִשְׂרָאֵל לֹא אָבָה לִי: וָאֲשַׁלְּחֵהוּ בִּשְׁרִירוּת לִבָּם, יֵלְכוּ בְּמוֹעֲצוֹתֵיהֶם: לוּ עַמִּי שֹׁמֵעַ לִי, יִשְׂרָאֵל בִּדְרָכַי יְהַלֵּכוּ: כִּמְעַט אוֹיְבֵיהֶם אַכְנִיעַ, וְעַל צָרֵיהֶם אָשִׁיב יָדִי: מְשַׂנְאֵי יהוה יְכַחֲשׁוּ לוֹ, וִיהִי עִתָּם לְעוֹלָם: וַיַּאֲכִילֵהוּ מֵחֵלֶב חִטָּה, וּמִצּוּר, דְּבַשׁ אַשְׂבִּיעֶךָ:","cond":["tishaaBeav","thu"]},{"kind":"text","text":"הַיּוֹם יוֹם שִׁשִּׁי בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["tishaaBeav","fri"]},{"kind":"text","text":"יהוה מָלָךְ גֵּאוּת לָבֵשׁ, לָבֵשׁ יהוה עֹז הִתְאַזָּר, אַף תִּכּוֹן תֵּבֵל בַּל תִּמּוֹט: נָכוֹן כִּסְאֲךָ מֵאָז, מֵעוֹלָם אָתָּה: נָשְׂאוּ נְהָרוֹת, יהוה, נָשְׂאוּ נְהָרוֹת קוֹלָם, יִשְׂאוּ נְהָרוֹת דָכְיָם: מִקֹּלוֹת מַיִם רַבִּים, אַדִּירִים מִשְׁבְּרֵי יָם, אַדִּיר בַּמָּרוֹם יהוה: עֵדֹתֶיךָ נֶאֶמְנוּ מְאֹד לְבֵיתְךָ נַאֲוָה קֹדֶשׁ, יהוה, לְאֹרֶךְ יָמִים:","cond":["tishaaBeav","fri"]},{"kind":"special","text":"בָּרְכִי נַפְשִׁי אֶת יהוה, יהוה אֱלֹהַי גָּדַלְתָּ מְּאֹד, הוֹד וְהָדָר לָבָשְׁתָּ:\nעֹטֶה אוֹר כַּשַּׂלְמָה נוֹטֶה שָׁמַיִם כַּיְרִיעָה:\nהַמְקָרֶה בַמַּיִם עֲלִיּוֹתָיו, הַשָּׂם עָבִים רְכוּבוֹ, הַמְהַלֵּךְ עַל כַּנְפֵי רוּחַ:\nעֹשֶׂה מַלְאָכָיו רוּחוֹת, מְשָׁרְתָיו אֵשׁ לֹהֵט:\nיָסַד אֶרֶץ עַל מְכוֹנֶיהָ, בַּל תִּמּוֹט עוֹלָם וָעֶד:\nתְּהוֹם כַּלְּבוּשׁ כִּסִּיתוֹ, עַל הָרִים יַעַמְדוּ מָיִם:\nמִן גַּעֲרָתְךָ יְנוּסוּן, מִן קוֹל רַעַמְךָ יֵחָפֵזוּן:\nיַעֲלוּ הָרִים, יֵרְדוּ בְקָעוֹת, אֶל מְקוֹם זֶה יָסַדְתָּ לָהֶם:\nגְּבוּל שַׂמְתָּ בַּל יַעֲבֹרוּן, בַּל יְשׁוּבוּן לְכַסּוֹת הָאָרֶץ:\nהַמְשַׁלֵּחַ מַעְיָנִים בַּנְּחָלִים בֵּין הָרִים יְהַלֵּכוּן:","cond":["tishaaBeav","rh"]},{"kind":"special","text":"יַשְׁקוּ כָּל חַיְתוֹ שָׂדָי, יִשְׁבְּרוּ פְרָאִים צְמָאָם:\nעֲלֵיהֶם עוֹף הַשָּׁמַיִם יִשְׁכּוֹן, מִבֵּין עֳפָאיִם יִתְּנוּ קוֹל:\nמַשְׁקֶה הָרִים מֵעֲלִיּוֹתָיו, מִפְּרִי מַעֲשֶׂיךָ תִּשְׂבַּע הָאָרֶץ:\nמַצְמִיחַ חָצִיר לַבְּהֵמָה וְעֵשֶׂב לַעֲבֹדַת הָאָדָם, לְהוֹצִיא לֶחֶם מִן הָאָרֶץ:\nוְיַיִן יְשַׂמַּח לְבַב אֱנוֹשׁ, לְהַצְהִיל פָּנִים מִשָּׁמֶן, וְלֶחֶם לְבַב אֱנוֹשׁ יִסְעָד:\nיִשְׂבְּעוּ עֲצֵי יהוה, אַרְזֵי לְבָנוֹן אֲשֶׁר נָטָע:\nאֲשֶׁר שָׁם צִפֳּרִים יְקַנֵּנוּ, חֲסִידָה בְּרוֹשִׁים בֵּיתָהּ:\nהָרִים הַגְּבֹהִים לַיְּעֵלִים, סְלָעִים מַחְסֶה לַשְׁפַנִּים:\nעָשָׂה יָרֵחַ לְמוֹעֲדִים, שֶׁמֶשׁ יָדַע מְבוֹאוֹ:\nתָּשֶׁת חֹשֶׁךְ וִיהִי לָיְלָה, בּוֹ תִרְמֹשׂ כָּל חַיְתוֹ יָעַר:\nהַכְּפִירִים שֹׁאֲגִים לַטָּרֶף וּלְבַקֵּשׁ מֵאֵל אָכְלָם:\nתִּזְרַח הַשֶּׁמֶשׁ יֵאָסֵפוּן וְאֶל מְעוֹנֹתָם יִרְבָּצוּן:","cond":["tishaaBeav","rh"]},{"kind":"special","text":"יֵצֵא אָדָם לְפָעֳלוֹ וְלַעֲבֹדָתוֹ עֲדֵי עָרֶב:\nמָה רַבּוּ מַעֲשֶׂיךָ יהוה, כֻּלָּם בְּחָכְמָה עָשִׂיתָ, מָלְאָה הָאָרֶץ קִנְיָנֶךָ:\nזֶה הַיָּם גָּדוֹל וּרְחַב יָדָיִם, שָׁם רֶמֶשׂ וְאֵין מִסְפָּר, חַיּוֹת קְטַנּוֹת עִם גְּדֹלוֹת:\nשָׁם אֳנִיּוֹת יְהַלֵּכוּן, לִוְיָתָן זֶה יָצַרְתָּ לְשַׂחֶק בּוֹ:\nכֻּלָּם אֵלֶיךָ יְשַׂבֵּרוּן לָתֵת אָכְלָם בְּעִתּוֹ:\nתִּתֵּן לָהֶם יִלְקֹטוּן, תִּפְתַּח יָדְךָ יִשְׂבְּעוּן טוֹב:\nתַּסְתִּיר פָּנֶיךָ יִבָּהֵלוּן, תֹּסֵף רוּחָם יִגְוָעוּן וְאֶל עֲפָרָם יְשׁוּבוּן:\nתְּשַׁלַּח רוּחֲךָ יִבָּרֵאוּן וּתְחַדֵּשׁ פְּנֵי אֲדָמָה:\nיְהִי כְבוֹד יהוה לְעוֹלָם, יִשְׂמַח יהוה בְּמַעֲשָׂיו:\nהַמַּבִּיט לָאָרֶץ וַתִּרְעָד, יִגַּע בֶּהָרִים וְיֶעֱשָׁנוּ:\nאָשִׁירָה לַיהוה בְּחַיָּי, אֲזַמְּרָה לֵאלֹהַי בְּעוֹדִי:\nיֶעֱרַב עָלָיו שִׂיחִי, אָנֹכִי אֶשְׂמַח בַּיהוה:\nיִתַּמּוּ חַטָּאִים מִן הָאָרֶץ וּרְשָׁעִים עוֹד אֵינָם, בָּרְכִי נַפְשִׁי אֶת יהוה, הַלְלוּיָהּ:","cond":["tishaaBeav","rh"]},{"kind":"instruction","text":"קדיש יתום","cond":["tishaaBeav"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":["tishaaBeav"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","ayt"]},{"kind":"instruction","text":"סיום התפילה","cond":["tishaaBeav"]},{"kind":"text","text":"קַוֵּה אֶל יהוה, חֲזַק וְיַאֲמֵץ לִבֶּךָ, וְקַוֵּה אֶל יהוה:\nאֵין קָדושׁ כַּיהוה, כִּי אֵין בִּלְתֶּךָ, וְאֵין צוּר כֵּאלֹהֵינוּ:\nכִּי מִי אֱלוֹהַּ מִבַּלְעֲדֵי יהוה, וּמִי צוּר זוּלָתִי אֱלֹהֵינוּ:\n\nאֵין כֵּאלֹהֵינוּ, אֵין כַּאדוֹנֵינוּ, אֵין כְּמַלְכֵּנוּ, אֵין כְּמוֹשִׁיעֵנוּ.\nמִי כֵאלֹהֵינוּ, מִי כַאדוֹנֵינוּ, מִי כְמַלְכֵּנוּ, מִי כְמוֹשִׁיעֵנוּ.\nנוֹדֶה לֵאלֹהֵינוּ, נוֹדֶה לַאדוֹנֵינוּ, נוֹדֶה לְמַלְכֵּנוּ, נוֹדֶה לְמוֹשִׁיעֵנוּ.\nבָּרוּךְ אֱלֹהֵינוּ, בָּרוּךְ אֲדוֹנֵינוּ, בָּרוּךְ מַלְכֵּנוּ, בָּרוּךְ מוֹשִׁיעֵנוּ.\nאַתָּה הוּא אֱלֹהֵינוּ, אַתָּה הוּא אֲדוֹנֵינוּ, אַתָּה הוּא מַלְכֵּנוּ, אַתָּה הוּא מוֹשִׁיעֵנוּ.\nאַתָּה הוּא שֶׁהִקְטִירוּ אֲבוֹתֵינוּ לְפָנֶיךָ אֶת קְטֹרֶת הַסַּמִים.","cond":["tishaaBeav"]},{"kind":"instruction","text":"פיטום הקטורת","cond":["tishaaBeav"]},{"kind":"text","text":"פִּטּוּם הַקְּטֹרֶת: הַצֳּרִי, וְהַצִּפֹּרֶן, הַחֶלְבְּנָה, וְהַלְּבוֹנָה, מִשְׁקַל שִׁבְעִים שִׁבְעִים מָנֶה, מֹר וּקְצִיעָה, שִׁבֹּלֶת נֵרְדְּ, וְכַרְכֹּם מִשְׁקַל שִׁשָּׁה עָשָׂר שִׁשָּׁה עָשָׂר מָנֶה, הַקֹּשְׁטְ שְׁנֵים עָשָׂר, וְקִלּוּפָה שְׁלֹשָׁה, קִנָּמוֹן תִּשְׁעָה, בֹּרִית כַּרְשִׁינָה תִּשְׁעָה קַבִּין. יֵין קַפְרִיסִין סְאִין תְּלָתָא וְקַבִּין תְּלָתָא, וְאִם אֵין לוֹ יֵין קַפְרִיסִין מֵבִיא חֲמַר חִוַּרִין עַתִּיק. מֶלַח סְדוֹמִית רֹבַע, מַעֲלֶה עָשָׁן כָּל שֶׁהוּא, רַבִּי נָתָן הַבַּבְלִי אוֹמֵר: אַף כִּפַּת הַיַּרְדֵּן כָּל שֶׁהוּא. וְאִם נָתַן בָּהּ דְּבַשׁ פְּסָלָהּ, וְאִם חִסַּר אַחַת מִכָּל סַמָּנֶיהָ חַיָּב מִיתָה.\n\nרַבָּן שִׁמְעוֹן בֶּן גַּמְלִיאֵל אוֹמֵר: הַצֳּרִי אֵינוֹ אֶלָּא שְׂרָף הַנּוֹטֵף מֵעֲצֵי הַקְּטָף. בֹּרִית כַּרְשִׁינָה שֶׁשָּׁפִין בָּהּ אֶת הַצִּפֹּרֶן כְּדֵי שֶׁתְּהֵא נָאָה, יֵין קַפְרִיסִין שֶׁשּׁוֹרִין בּוֹ אֶת הַצִּפֹּרֶן כְּדֵי שֶׁתְּהֵא עַזָּה. וַהֲלֹא מֵי רַגְלַיִם יָפִין לָהּ, אֶלָּא שֶׁאֵין מַכְנִיסִין מֵי רַגְלַיִם בַּמִקְדָּשׁ מִפְּנֵי הַכָּבוֹד.\n\nתָּנָא דְבֵי אֵלִיָּהוּ: כָּל הַשּׁוֹנֶה הֲלָכוֹת בְּכָל יוֹם מֻבְטָח לוֹ שֶׁהוּא בֶּן עוֹלָם הַבָּא, שֶׁנֶּאֱמַר: הֲלִיכוֹת עוֹלָם לוֹ: אַל תִּקְרֵי הֲלִיכות אֶלָּא הֲלָכוֹת. אָמַר רַבִּי אֶלְעָזָר אָמַר רַבִּי חֲנִינָא: תַּלְמִידֵי חֲכָמִים מַרְבִּים שָׁלוֹם בָּעוֹלָם, שֶׁנֶּאֱמַר: וְכָל בָּנַיִךְ לִמּוּדֵי יהוה וְרַב שְׁלוֹם בָּנָיִךְ: אַל תִּקְרֵי בָּנָיִךְ אֶלָּא בּוֹנָיִךְ. שָׁלוֹם רָב לְאֹהֲבֵי תוֹרָתֶךָ, וְאֵין לָמוֹ מִכְשׁוֹל: יְהִי שָׁלוֹם בְּחֵילֵךְ, שַׁלְוָה בְּאַרְמְנוֹתָיִךְ: לְמַעַן אַחַי וְרֵעָי אֲדַבְּרָה נָּא שָׁלוֹם בָּךְ: לְמַעַן בֵּית יהוה אֱלֹהֵינוּ אֲבַקְשָׁה טוֹב לָךְ: יהוה עֹז לְעַמּוֹ יִתֵּן, יהוה יְבָרֵךְ אֶת עַמּוֹ בַשָּׁלוֹם:","cond":["tishaaBeav"]},{"kind":"instruction","text":"קדיש דרבנן","cond":["tishaaBeav"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":["tishaaBeav"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","ayt"]},{"kind":"text","text":"עַל יִשְׂרָאֵל וְעַל רַבָּנָן וְעַל תַּלְמִידֵיהוֹן וְעַל כָּל תַּלְמִידֵי תַלְמִידֵיהוֹן, וְעַל כָּל מָאן דְּעָסְקִין בְּאוֹרַיְתָא, דִּי בְאַתְרָא (קַדִּישָׁא) הָדֵין וְדִי בְכָל אֲתָר וַאֲתָר, יְהֵא לְהוֹן וּלְכוֹן שְׁלָמָא רַבָּא, חִנָּא וְחִסְדָּא, וְרַחֲמֵי וְחַיֵּי אֲרִיכֵי וּמְזוֹנֵי רְוִיחֵי וּפֻרְקָנָא מִן קֳדָם אֲבוּהוֹן דִּי בִשְׁמַיָּא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","ayt"]}],"arvit":[{"kind":"special","text":"תפילת יום העצמאות ויום שחרור ירושלים","cond":["yerushalayim"]},{"kind":"instruction","text":"לפני התפילה אומרים:","cond":["yerushalayim"]},{"kind":"instruction","text":"תהלים פרק ק\"ז","cond":["yerushalayim"]},{"kind":"text","text":"הֹדוּ לַיהוה כִּי-טוֹב, כִּי לְעוֹלָם חַסְדּוֹ: יֹאמְרוּ גְּאוּלֵי יהוה אֲשֶׁר גְּאָלָם מִיַּד-צָר: וּמֵאֲרָצוֹת קִבְּצָם, מִמִּזְרָח וּמִמַּעֲרָב מִצָּפוֹן וּמִיָּם: תָּעוּ בַמִּדְבָּר בִּישִׁימוֹן דָּרֶךְ, עִיר מוֹשָׁב לֹא מָצָאוּ: רְעֵבִים גַּם-צְמֵאִים, נַפְשָׁם בָּהֶם תִּתְעַטָּף: וַיִּצְעֲקוּ אֶל-יהוה בַּצַּר לָהֶם, מִמְּצוּקוֹתֵיהֶם יַצִּילֵם: וַיַּדְרִיכֵם בְּדֶרֶךְ יְשָׁרָה, לָלֶכֶת אֶל-עִיר מוֹשָׁב: יוֹדוּ לַיהוה חַסְדּוֹ, וְנִפְלְאוֹתָיו לִבְנֵי אָדָם: כִּי-הִשְׂבִּיעַ נֶפֶשׁ שׁוֹקֵקָה, וְנֶפֶשׁ רְעֵבָה מִלֵּא-טוֹב: יֹשְׁבֵי חֹשֶׁךְ וְצַלְמָוֶת, אֲסִירֵי עֳנִי וּבַרְזֶל: כִּי-הִמְרוּ אִמְרֵי-אֵל, וַעֲצַת עֶלְיוֹן נָאָצוּ: וַיַּכְנַע בֶּעָמָל לִבָּם, כָּשְׁלוּ וְאֵין עֹזֵר: וַיִּזְעֲקוּ אֶל-יהוה בַּצַּר לָהֶם, מִמְּצֻקוֹתֵיהֶם יוֹשִׁיעֵם: יוֹצִיאֵם מֵחֹשֶׁךְ וְצַלְמָוֶת, וּמוֹסְרוֹתֵיהֶם יְנַתֵּק: יוֹדוּ לַיהוה חַסְדּוֹ, וְנִפְלְאוֹתָיו לִבְנֵי אָדָם: כִּי-שִׁבַּר דַּלְתוֹת נְחֹשֶׁת, וּבְרִיחֵי בַרְזֶל גִּדֵּעַ: אֱוִלִים מִדֶּרֶךְ פִּשְׁעָם, וּמֵעֲוׂנֹתֵיהֶם יִתְעַנּוּ: כָּל-אֹכֶל תְּתַעֵב נַפְשָׁם, וַיַּגִּיעוּ עַד-שַׁעֲרֵי מָוֶת: וַיִּזְעֲקוּ אֶל-יהוה בַּצַּר לָהֶם, מִמְּצֻקוֹתֵיהֶם יוֹשִׁיעֵם: יִשְׁלַח דְּבָרוֹ וְיִרְפָּאֵם, וִימַלֵּט מִשְּׁחִיתוֹתָם: יוֹדוּ לַיהוה חַסְדּוֹ, וְנִפְלְאוֹתָיו לִבְנֵי אָדָם: וְיִזְבְּחוּ זִבְחֵי תוֹדָה, וִיסַפְּרוּ מַעֲשָׂיו בְּרִנָּה: יוֹרְדֵי הַיָּם בָּאֳנִיּוֹת, עֹשֵׂי מְלָאכָה בְּמַיִם רַבִּים: הֵמָּה רָאוּ מַעֲשֵׂי יהוה וְנִפְלְאוֹתָיו בִּמְצוּלָה: וַיּאמֶר, וַיַּעֲמֵד רוּחַ סְעָרָה, וַתְּרוֹמֵם גַּלָּיו: יַעֲלוּ שָׁמַיִם יֵרְדוּ תְהוֹמוֹת, נַפְשָׁם בְּרָעָה תִתְמוֹגָג: יָחוֹגּוּ וְיָנוּעוּ כַּשִּׁכּוֹר, וְכָל-חָכְמָתָם תִּתְבַּלָּע: וַיִּצְעֲקוּ אֶל-יהוה בַּצַּר לָהֶם, וּמִמְּצוּקתֵיהֶם יוֹצִיאֵם: יָקֵם סְעָרָה לִדְמָמָה, וַיֶּחֱשׁוּ גַּלֵּיהֶם: וַיִּשְׂמְחוּ כִי-יִשְׁתֹּקוּ, וַיַּנְחֵם אֶל-מְחוֹז חֶפְצָם: יוֹדוּ לַיהוה חַסְדּוֹ, וְנִפְלְאוֹתָיו לִבְנֵי אָדָם: וִירוֹמְמוּהוּ בִּקְהַל-עָם, וּבְמוֹשַׁב זְקֵנִים יְהַלְלוּהוּ: יָשֵׂם נְהָרוֹת לְמִדְבָּר, וּמֹצָאֵי מַיִם לְצִמָּאוֹן: אֶרֶץ פְּרִי לִמְלֵחָה מֵרָעַת יוֹשְׁבֵי בָהּ: יָשֵׂם מִדְבָּר לַאֲגַם-מַיִם, וְאֶרֶץ צִיָּה לְמֹצָאֵי מָיִם: וַיּוֹשֶׁב שָׁם רְעֵבִים, וַיְכוֹנְנוּ עִיר מוֹשָׁב: וַיִּזְרְעוּ שָׂדוֹת וַיִּטְּעוּ כְרָמִים, וַיַּעֲשׂוּ פְּרִי תְבוּאָה: וַיְבָרְכֵם וַיִּרְבּוּ מְאֹד, וּבְהֶמְתָּם לֹא יַמְעִיט: וַיִּמְעֲטוּ וַיָּשֹׁחוּ מֵעֹצֶר רָעָה וְיָגוֹן: שֹׁפֵךְ בּוּז עַל-נְדִיבִים, וַיַּתְעֵם בְּתֹהוּ לֹא-דָרֶךְ: וַיְשַׂגֵּב אֶבְיוֹן מֵעוֹנִי, וַיָּשֶׂם כַּצֹּאן מִשְׁפָּחוֹת: יִרְאוּ יְשָׁרִים וְיִשְׂמָחוּ, וְכָל-עַוְלָה קָפְצָה פִּיהָ: מִי-חָכָם וְיִשְׁמָר-אֵלֶּה, וְיִתְבּוֹנְנוּ חַסְדֵּי יהוה:","cond":["yerushalayim"]},{"kind":"instruction","text":"תהלים פרק צ\"ז","cond":["yerushalayim"]},{"kind":"text","text":"יהוה מָלָךְ תָּגֵל הָאָרֶץ, יִשְׂמְחוּ אִיִּים רַבִּים: עָנָן וַעֲרָפֶל סְבִיבָיו, צֶדֶק וּמִשְׁפָּט מְכוֹן כִּסְאוֹ: אֵשׁ לְפָנָיו תֵּלֵךְ וּתְלַהֵט סָבִיב צָרָיו: הֵאִירוּ בְרָקָיו תֵּבֵל, רָאֲתָה וַתָּחֵל הָאָרֶץ: הָרִים כַּדּוֹנַג נָמַסּוּ, מִלִּפְנֵי יהוה, מִלִּפְנֵי אֲדוֹן כָּל-הָאָרֶץ: הִגִּידוּ הַשָּׁמַיִם צִדְקוֹ וְרָאוּ כָל-הָעַמִּים כְּבוֹדוֹ: יֵבשׁוּ כָּל-עֹבְדֵי פֶסֶל הַמִּתְהַלְלִים בָּאֱלִילִים, הִשְׁתַּחֲווּ-לוֹ כָּל-אֱלֹהִים: שָׁמְעָה וַתִּשְׂמַח צִיּוֹן וַתָּגֵלְנָה בְּנוֹת יְהוּדָה, לְמַעַן מִשְׁפָּטֶיךָ, יהוה: כִּי-אַתָּה יהוה עֶלְיוֹן עַל-כָּל-הָאָרֶץ, מְאֹד נַעֲלֵיתָ עַל-כָּל-אֱלֹהִים: אֹהֲבֵי יהוה שִׂנְאוּ רָע, שֹׁמֵר נַפְשׁוֹת חֲסִידָיו, מִיַּד רְשָׁעִים יַצִּילֵם: אוֹר זָרֻעַ לַצַּדִּיק וּלְיִשְׁרֵי-לֵב שִׂמְחָה: שִׂמְחוּ צַדִּיקִים בַּיהוה, וְהוֹדוּ לְזֵכֶר קָדְשׁוֹ:","cond":["yerushalayim"]},{"kind":"instruction","text":"תהלים פרק צ\"ח","cond":["yerushalayim"]},{"kind":"text","text":"מִזְמוֹר, שִׁירוּ לַיהוה שִׁיר חָדָשׁ כִּי-נִפְלָאוֹת עָשָׂה, הוֹשִׁיעָה-לּוֹ יְמִינוֹ וּזְרוֹעַ קָדְשׁוֹ: הוֹדִיעַ יהוה יְשׁוּעָתוֹ, לְעֵינֵי הַגּוֹיִם גִּלָּה צִדְקָתוֹ: זָכַר חַסְדּוֹ וֶאֱמוּנָתוֹ לְבֵית יִשְׂרָאֵל, רָאוּ כָל-אַפְסֵי-אָרֶץ אֵת יְשׁוּעַת אֱלֹהֵינוּ: הָרִיעוּ לַיהוה כָּל-הָאָרֶץ, פִּצְחוּ וְרַנְּנוּ וְזַמֵּרוּ: זַמְּרוּ לַיהוה בְּכִנּוֹר, בְּכִנּוֹר וְקוֹל זִמְרָה: בַּחֲצֹצְרוֹת וְקוֹל שׁוֹפָר, הָרִיעוּ לִפְנֵי הַמֶּלֶךְ יהוה: יִרְעַם הַיָּם וּמְלֹאוֹ, תֵּבֵל וְישְׁבֵי בָהּ: נְהָרוֹת יִמְחֲאוּ-כָף, יַחַד הָרִים יְרַנֵּנוּ: לִפְנֵי-יהוה כִּי בָא לִשְׁפֹּט הָאָרֶץ, יִשְׁפֹּט-תֵּבֵל בְּצֶדֶק וְעַמִּים בְּמֵישָׁרִים:","cond":["yerushalayim"]},{"kind":"instruction","text":"ואומרים בית בית:","cond":["yerushalayim"]},{"kind":"text","text":"הִתְעוֹרְרִי הִתְעוֹרְרִי,\nכִּי בָא אוֹרֵךְ קוּמִי אוֹרִי.\nעוּרִי עוּרִי שִׁיר דַּבֵּרִי,\nכְּבוֹד יהוה עָלַיִךְ נִגְלָה.\nזֶה הַיּוֹם עָשָׂה יהוה, נָגִילָה וְנִשְׂמְחָה בוֹ:\n\nלֹא תֵּבֹשִׁי וְלֹא תִּכָּלְמִי\nמַה תִּשְׁתּוֹחֲחִי וּמַה תֶּהֱמִי\nבָּךְ יֶחֱסוּ עֲנִיֵּי עַמִּי\nוְנִבְנְתָה עִיר עַל תִּלָּהּ\nזֶה הַיּוֹם עָשָׂה יהוה, נָגִילָה וְנִשְׂמְחָה בוֹ:\n\nיָמִין וּשְׂמֹאל תִּפְרֹצִי\nוְאֶת יהוה תַּעֲרִיצִי\nעַל יַד אִישׁ בֶּן פַּרְצִי\nוְנִשְׂמְחָה וְנָגִילָה\nזֶה הַיּוֹם עָשָׂה יהוה, נָגִילָה וְנִשְׂמְחָה בוֹ:","cond":["yerushalayim"]},{"kind":"header","text":"תפילת ערבית","cond":["yerushalayim"]},{"kind":"text","text":"וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית, וְהִרְבָּה לְהָשִׁיב אַפּוֹ וְלֹא יָעִיר כָּל חֲמָתוֹ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":[]},{"kind":"instruction","text":"חזן:","cond":[]},{"kind":"text","text":"בָּרְכוּ אֶת יהוה הַמְבֹרָךְ.","cond":[]},{"kind":"instruction","text":"קהל וחזן:","cond":[]},{"kind":"text","text":"בָּרוּךְ יהוה הַמְבֹרָךְ לְעוֹלָם וָעֶד.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר בִּדְבָרוֹ מַעֲרִיב עֲרָבִים, בְּחָכְמָה פּוֹתֵחַ שְׁעָרִים, וּבִתְבוּנָה מְשַׁנֶּה עִתִּים וּמַחֲלִיף אֶת הַזְּמַנִּים, וּמְסַדֵּר אֶת הַכּוֹכָבִים בְּמִשְׁמְרוֹתֵיהֶם בָּרָקִיעַ כִּרְצוֹנוֹ, בּוֹרֵא יוֹם וָלָיְלָה, גּוֹלֵל אוֹר מִפְּנֵי חֹשֶׁךְ וְחֹשֶׁךְ מִפְּנֵי אוֹר, וּמַעֲבִיר יוֹם וּמֵבִיא לָיְלָה, וּמַבְדִּיל בֵּין יוֹם וּבֵין לָיְלָה, יהוה צְבָאוֹת שְׁמוֹ. אֵל חַי וְקַיָּם תָּמִיד, יִמְלֹךְ עָלֵינוּ לְעוֹלָם וָעֶד. בָּרוּךְ אַתָּה יהוה, הַמַּעֲרִיב עֲרָבִים.","cond":[]},{"kind":"text","text":"אַהֲבַת עוֹלָם בֵּית יִשְׂרָאֵל עַמְּךָ אָהַבְתָּ, תּוֹרָה וּמִצְוׂת חֻקִּים וּמִשְׁפָּטִים אוֹתָנוּ לִמַּדְתָּ, עַל כֵּן יהוה אֱלֹהֵינוּ, בְּשָׁכְבֵנוּ וּבְקוּמֵנוּ נָשִׂיחַ בְּחֻקֶּיךָ, וְנִשְׂמַח בְּדִבְרֵי תוֹרָתֶךָ וּבְמִצְוׂתֶיךָ לְעוֹלָם וָעֶד, כִּי הֵם חַיֵּינוּ וְאֹרֶךְ יָמֵינוּ, וּבָהֶם נֶהְגֶּה יוֹמָם וָלָיְלָה. וְאַהֲבָתְךָ אַל תָּסִיר מִמֶּנּוּ לְעוֹלָמִים. בָּרוּךְ אַתָּה יהוה, אוֹהֵב עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"header","text":"קריאת שמע","cond":[]},{"kind":"instruction","text":"יחיד אומר:","cond":[]},{"kind":"text","text":"אֵל מֶלֶךְ נֶאֱמָן.","cond":[]},{"kind":"text","text":"שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:","cond":[]},{"kind":"instruction","text":"בלחש:","cond":[]},{"kind":"text","text":"בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד.\n\nוְאָהַבְתָּ אֵת יהוה אֱלֹהֶיךָ, בְּכָל לְבָבְךָ וּבְכָל נַפְשְׁךָ וּבְכָל מְאֹדֶךָ: וְהָיוּ הַדְּבָרִים הָאֵלֶּה אֲשֶׁר אָנֹכִי מְצַוְּךָ הַיּוֹם, עַל לְבָבֶךָ: וְשִׁנַּנְתָּם לְבָנֶיךָ וְדִבַּרְתָּ בָּם, בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ: וּקְשַׁרְתָּם לְאוֹת עַל יָדֶךָ, וְהָיוּ לְטֹטָפֹת בֵּין עֵינֶיךָ: וּכְתַבְתָּם עַל מְזֻזוֹת בֵּיתֶךָ וּבִשְׁעָרֶיךָ:","cond":[]},{"kind":"text","text":"וְהָיָה אִם שָׁמֹעַ תִּשְׁמְעוּ אֶל מִצְוׂתַי, אֲשֶׁר אָנֹכִי מְצַוֶּה אֶתְכֶם הַיּוֹם, לְאַהֲבָה אֶת יהוה אֱלֹהֵיכֶם וּלְעָבְדוֹ, בְּכָל לְבַבְכֶם וּבְכָל נַפְשְׁכֶם: וְנָתַתִּי מְטַר אַרְצְכֶם בְּעִתּוֹ, יוֹרֶה וּמַלְקוֹשׁ, וְאָסַפְתָּ דְגָנֶךָ וְתִירֹשְׁךָ וְיִצְהָרֶךָ: וְנָתַתִּי עֵשֶׂב בְּשָׂדְךָ לִבְהֶמְתֶּךָ, וְאָכַלְתָּ וְשָׂבָעְתָּ: הִשָּׁמְרוּ לָכֶם פֶּן יִפְתֶּה לְבַבְכֶם, וְסַרְתֶּם וַעֲבַדְתֶּם אֱלֹהִים אֲחֵרִים וְהִשְׁתַּחֲוִיתֶם לָהֶם: וְחָרָה אַף יהוה בָּכֶם, וְעָצַר אֶת הַשָּׁמַיִם וְלֹא יִהְיֶה מָטָר, וְהָאֲדָמָה לֹא תִתֵּן אֶת יְבוּלָהּ, וַאֲבַדְתֶּם מְהֵרָה מֵעַל הָאָרֶץ הַטֹּבָה אֲשֶׁר יהוה נֹתֵן לָכֶם: וְשַׂמְתֶּם אֶת דְּבָרַי אֵלֶּה עַל לְבַבְכֶם וְעַל נַפְשְׁכֶם, וּקְשַׁרְתֶּם אֹתָם לְאוֹת עַל יֶדְכֶם וְהָיוּ לְטוֹטָפֹת בֵּין עֵינֵיכֶם: וְלִמַּדְתֶּם אֹתָם אֶת בְּנֵיכֶם לְדַבֵּר בָּם, בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ: וּכְתַבְתָּם עַל מְזוּזוֹת בֵּיתֶךָ וּבִשְׁעָרֶיךָ: לְמַעַן יִרְבּוּ יְמֵיכֶם וִימֵי בְנֵיכֶם עַל הָאֲדָמָה אֲשֶׁר נִשְׁבַּע יהוה לַאֲבֹתֵיכֶם לָתֵת לָהֶם, כִּימֵי הַשָּׁמַיִם עַל הָאָרֶץ:","cond":[]},{"kind":"text","text":"וַיֹּאמֶר יהוה אֶל מֹשֶׁה לֵּאמֹר: דַּבֵּר אֶל בְּנֵי יִשְׂרָאֵל וְאָמַרְתָּ אֲלֵהֶם, וְעָשׂוּ לָהֶם צִיצִת עַל כַּנְפֵי בִגְדֵיהֶם לְדֹרֹתָם, וְנָתְנוּ עַל צִיצִת הַכָּנָף פְּתִיל תְּכֵלֶת: וְהָיָה לָכֶם לְצִיצִת, וּרְאִיתֶם אֹתוֹ, וּזְכַרְתֶּם אֶת כָּל מִצְוׂת יהוה וַעֲשִׂיתֶם אֹתָם, וְלֹא תָתֻרוּ אַחֲרֵי לְבַבְכֶם וְאַחֲרֵי עֵינֵיכֶם אֲשֶׁר אַתֶּם זֹנִים אַחֲרֵיהֶם: לְמַעַן תִּזְכְּרוּ וַעֲשִׂיתֶם אֶת כָּל מִצְוׂתָי, וִהְיִיתֶם קְדֹשִׁים לֵאלֹהֵיכֶם: אֲנִי יהוה אֱלֹהֵיכֶם אֲשֶׁר הוֹצֵאתִי אֶתְכֶם מֵאֶרֶץ מִצְרַיִם, לִהְיוֹת לָכֶם לֵאלֹהִים, אֲנִי יהוה אֱלֹהֵיכֶם:","cond":[]},{"kind":"text","text":"אֱמֶת","cond":[]},{"kind":"instruction","text":"הש\"ץ חוזר ואומר:","cond":[]},{"kind":"text","text":"יהוה אֱלֹהֵיכֶם: אֱמֶת\n\nוֶאֱמוּנָה כָּל זֹאת וְקַיָּם עָלֵינוּ, כִּי הוּא יהוה אֱלֹהֵינוּ וְאֵין זוּלָתוֹ, וַאֲנַחְנוּ יִשׂרָאֵל עַמּוֹ. הַפּוֹדֵנוּ מִיַּד מְלָכִים, מַלְכֵּנוּ הַגּוֹאֲלֵנוּ מִכַּף כָּל הֶעָרִיצִים, הָאֵל הַנִּפְרָע לָנוּ מִצָּרֵינוּ, וְהַמְשַׁלֵּם גְּמוּל לְכָל אוֹיְבֵי נַפְשֵׁנוּ. הָעוֹשֶׂה גְדוֹלוֹת עַד אֵין חֵקֶר, וְנִפְלָאוֹת עַד אֵין מִסְפָּר, הַשָּׂם נַפְשֵׁנוּ בַּחַיִּים, וְלֹא נָתַן לַמּוֹט רַגְלֵנוּ. הַמַּדְרִיכֵנוּ עַל בָּמוֹת אוֹיְבֵינוּ, וַיָּרֶם קַרְנֵנוּ עַל כָּל שׂוֹנְאֵינוּ. הָעוֹשֶׂה לָּנוּ נִסִּים וּנְקָמָה בְּפַרְעה, אוֹתוֹת וּמוֹפְתִים בְּאַדְמַת בְּנֵי חָם, הַמַּכֶּה בְעֶבְרָתוֹ כָּל בְּכוֹרֵי מִצְרָיִם, וַיּוֹצֵא אֶת עַמּוֹ יִשְׂרָאֵל מִתּוֹכָם לְחֵרוּת עוֹלָם. הַמַּעֲבִיר בָּנָיו בֵּין גִּזְרֵי יַם סוּף, אֶת רוֹדְפֵיהֶם וְאֶת שׂוֹנְאֵיהֶם בִּתְהוֹמוֹת טִבַּע. וְרָאוּ בָנָיו גְּבוּרָתוֹ, שִׁבְּחוּ וְהוֹדוּ לִשְׁמוֹ. וּמַלְכוּתוֹ, בְּרָצון קִבְּלוּ עֲלֵיהֶם, משֶׁה וּבְנֵי יִשְׂרָאֵל לְךָ עָנוּ שִׁירָה בְּשִׂמְחָה רַבָּה, וְאָמְרוּ כֻלָּם:\n\nמִי כָמֹכָה בָּאֵלִם יהוה, מִי כָּמֹכָה נֶאְדָּר בַּקֹּדֶשׁ, נוֹרָא תְהִלֹּת עֹשֵׂה פֶלֶא:\n\nמַלְכוּתְךָ רָאוּ בָנֶיךָ, בּוֹקֵעַ יָם לִפְנֵי משֶׁה, \"זֶה אֵלִי\" עָנוּ, וְאָמְרוּ:\n\nיהוה יִמְלֹךְ לְעֹלָם וָעֶד:\n\nוְנֶאֱמַר: כִּי פָדָה יהוה אֶת יַעֲקֹב וּגְאָלוֹ מִיַּד חָזָק מִמֶּנּוּ: בָּרוּךְ אַתָּה יהוה, גָּאַל יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"הַשְׁכִּיבֵנוּ יהוה אֱלֹהֵינוּ לְשָׁלוֹם, וְהַעֲמִידֵנוּ מַלְכֵּנוּ לְחַיִּים, וּפְרֹשׂ עָלֵינוּ סֻכַּת שְׁלוֹמֶךָ, וְתַקְּנֵנוּ בְּעֵצָה טוֹבָה מִלְּפָנֶיךָ, וְהוֹשִׁיעֵנוּ לְמַעַן שְׁמֶךָ. וְהָגֵן בַּעֲדֵנוּ, וְהָסֵר מֵעָלֵינוּ אוֹיֵב, דֶּבֶר וְחֶרֶב וְרָעָב וְיָגוֹן. וְהָסֵר שָׂטָן מִלְּפָנֵינוּ וּמֵאַחֲרֵינוּ, וּבְצֵל כְּנָפֶיךָ תַּסְתִּירֵנוּ, כִּי אֵל שׁוֹמְרֵנוּ וּמַצִּילֵנוּ אָתָּה, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה. וּשְׁמוֹר צֵאתֵנוּ וּבוֹאֵנוּ לְחַיִּים וּלְשָׁלוֹם מֵעַתָּה וְעַד עוֹלָם. בָּרוּךְ אַתָּה יהוה, שׁוֹמֵר עַמּוֹ יִשְׂרָאֵל לָעַד.","cond":[]},{"kind":"text","text":"בָּרוּךְ יהוה לְעוֹלָם אָמֵן וְאָמֵן: בָּרוּךְ יהוה מִצִּיּוֹן, שֹׁכֵן יְרוּשָׁלָיִם הַלְלוּיָהּ: בָּרוּךְ יהוה אֱלֹהִים אֱלֹהֵי יִשְׂרָאֵל, עֹשֵׂה נִפְלָאוֹת לְבַדּוֹ: וּבָרוּךְ שֵׁם כְּבוֹדוֹ לְעוֹלָם, וְיִמָּלֵא כְבוֹדוֹ אֶת כָּל הָאָרֶץ אָמֵן וְאָמֵן: יְהִי כְבוֹד יהוה לְעוֹלָם, יִשְׂמַח יהוה בְּמַעֲשָׂיו: יְהִי שֵׁם יהוה מְבֹרָךְ מֵעַתָּה וְעַד עוֹלָם: כִּי לֹא יִטֹּשׁ יהוה אֶת עַמּו בַּעֲבוּר שְׁמוֹ הַגָּדוֹל, כִּי הוֹאִיל יהוה לַעֲשׂוֹת אֶתְכֶם לוֹ לְעָם: וַיַּרְא כָּל הָעָם וַיִּפְּלוּ עַל פְּנֵיהֶם וַיֹּאמְרוּ, יהוה הוּא הָאֱלֹהִים, יהוה הוּא הָאֱלֹהִים: וְהָיָה יהוה לְמֶלֶךְ עַל כָּל הָאָרֶץ, בַּיּוֹם הַהוּא יִהְיֶה יהוה אֶחָד וּשְׁמוֹ אֶחָד: יְהִי חַסְדְּךָ יהוה עָלֵינוּ כַּאֲשֶׁר יִחַלְנוּ לָךְ: הוֹשִׁיעֵנוּ יהוה אֱלֹהֵינוּ וְקַבְּצֵנוּ מִן הַגּוֹיִם, לְהוֹדוֹת לְשֵׁם קָדְשֶׁךָ לְהִשְׁתַּבֵּחַ בִּתְהִלָּתֶךָ: כָּל גּוֹיִם אֲשֶׁר עָשִׂיתָ יָבֹאוּ וְיִשְׁתַּחֲווּ לְפָנֶיךָ אֲדֹנָי וִיכַבְּדוּ לִשְׁמֶךָ: כִּי גָדוֹל אַתָּה וְעֹשֵׂה נִפְלָאוֹת, אַתָּה אֱלֹהִים לְבַדֶּךָ: וַאֲנַחְנוּ עַמְּךָ וְצֹאן מַרְעִיתֶךָ נוֹדֶה לְךָ לְעוֹלָם, לְדוֹר וָדוֹר נְסַפֵּר תְּהִלָּתֶךָ: בָּרוּךְ יהוה בַּיּוֹם, בָּרוּךְ יהוה בַּלָּיְלָה, בָּרוּךְ יהוה בְּשָׁכְבֵנוּ, בָּרוּךְ יהוה בְּקוּמֵנוּ. כִּי בְיָדְךָ נַפְשׁוֹת הַחַיִּים וְהַמֵּתִים. אֲשֶׁר בְּיָדוֹ נֶפֶשׁ כָּל חָי וְרוּחַ כָּל בְּשָׂר אִישׁ: בְּיָדְךָ אַפְקִיד רוּחִי, פָּדִיתָה אוֹתִי יהוה אֵל אֱמֶת: אֱלֹהֵינוּ שֶׁבַּשָּׁמַיִם, יַחֵד שִׁמְךָ וְקַיֵּם מַלְכוּתְךָ תָּמִיד, וּמְלֹךְ עָלֵינוּ לְעוֹלָם וָעֶד. יִרְאוּ עֵינֵינוּ וְיִשְׂמַח לִבֵּנוּ וְתָגֵל נַפְשֵׁנוּ בִּישׁוּעָתְךָ בֶּאֱמֶת בֶּאֱמֹר לְצִיּוֹן מָלַךְ אֱלֹהָיִךְ. יהוה מֶלֶךְ, יהוה מָלָךְ, יהוה יִמְלֹךְ לְעוֹלָם וָעֶד. כִּי הַמַּלְכוּת שֶׁלְּךָ הִיא, וּלְעוֹלְמֵי עַד תִּמְלֹךְ בְּכָבוֹד, כִּי אֵין לָנוּ מֶלֶךְ אֶלָּא אָתָּה. בָּרוּךְ אַתָּה יהוה, הַמֶּלֶךְ בִּכְבוֹדוֹ תָּמִיד יִמְלֹךְ עָלֵינוּ לְעוֹלָם וָעֶד וְעַל כָּל מַעֲשָׂיו.","cond":["chul"]},{"kind":"instruction","text":"חצי קדיש","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":[]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"header","text":"עמידה","cond":[]},{"kind":"instruction","text":"תפילת העמידה","cond":[]},{"kind":"text","text":"אֲדֹנָי, שְׂפָתַי תִּפְתָּח, וּפִי יַגִּיד תְּהִלָּתֶךָ:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק, וֵאלֹהֵי יַעֲקֹב, הָאֵל הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, וְקוֹנֵה הַכֹּל, וְזוֹכֵר חַסְדֵי אָבוֹת, וּמֵבִיא גוֹאֵל לִבְנֵי בְנֵיהֶם לְמַעַן שְׁמוֹ בְּאַהֲבָה.","cond":[]},{"kind":"special","text":"זָכְרֵנוּ לְחַיִּים, מֶלֶךְ חָפֵץ בַּחַיִּים, וְכָתְבֵנוּ בְּסֵפֶר הַחַיִּים, לְמַעַנְךָ אֱלֹהִים חַיִּים.","cond":["ayt"]},{"kind":"text","text":"מֶלֶךְ עוֹזֵר וּמוֹשִׁיעַ וּמָגֵן. בָּרוּךְ אַתָּה יהוה, מָגֵן אַבְרָהָם.","cond":[]},{"kind":"text","text":"אַתָּה גִּבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֵּה מֵתִים אַתָּה רַב לְהוֹשִׁיעַ,","cond":[]},{"kind":"summer","text":"מוֹרִיד הַטָּל,","cond":["summerTal"]},{"kind":"winter","text":"מַשִּׁיב הָרוּחַ וּמוֹרִיד הַגֶּשֶׁם,","cond":["winterTal"]},{"kind":"text","text":"מְכַלְכֵּל חַיִּים בְּחֶסֶד, מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים, סוֹמֵךְ נוֹפְלִים, וְרוֹפֵא חוֹלִים וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמוּנָתוֹ לִישֵׁנֵי עָפָר. מִי כָמוֹךָ בַּעַל גְּבוּרוֹת וּמִי דּוֹמֶה לָךְ, מֶלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִיחַ יְשׁוּעָה.","cond":[]},{"kind":"special","text":"מִי כָמוֹךָ אַב הָרַחֲמִים, זוֹכֵר יְצוּרָיו לְחַיִּים בְּרַחֲמִים.","cond":["ayt"]},{"kind":"text","text":"וְנֶאֱמָן אַתָּה לְהַחֲיוֹת מֵתִים. בָּרוּךְ אַתָּה יהוה, מְחַיֵּה הַמֵּתִים.","cond":[]},{"kind":"text","text":"אַתָּה קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ וּקְדוֹשִׁים בְּכָל יוֹם יְהַלְלוּךָ סֶּלָה.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הָאֵל הַקָּדוֹשׁ.","cond":["noayt"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יהוה, הַמֶּלֶךְ הַקָּדוֹשׁ.","cond":["ayt"]},{"kind":"text","text":"אַתָּה חוֹנֵן לְאָדָם דַּעַת וּמְלַמֵּד לֶאֱנוֹשׁ בִּינָה.","cond":[]},{"kind":"text","text":"חָנֵּנוּ מֵאִתְּךָ דֵעָה בִּינָה וְהַשְׂכֵּל.","cond":["noChonantanu"]},{"kind":"special","text":"אַתָּה חוֹנַנְתָּנוּ לְמַדָּע תּוֹרָתֶךָ וַתְּלַמְּדֵנוּ לַעֲשׂוֹת חֻקֵּי רְצוֹנֶךָ, וַתַּבְדֵּל יהוה אֱלֹהֵינוּ בֵּין קֹדֶשׁ לְחוֹל, בֵּין אוֹר לְחֹשֶׁךְ, בֵּין יִשְׂרָאֵל לָעַמִּים, בֵּין יוֹם הַשְּׁבִיעִי לְשֵׁשֶׁת יְמֵי הַמַּעֲשֶׂה. אָבִינוּ מַלְכֵּנוּ הָחֵל עָלֵינוּ הַיָּמִים הַבָּאִים לִקְרָאתֵנוּ לְשָׁלוֹם, חֲשׂוּכִים מִכָּל חֵטְא וּמְנֻקִּים מִכָּל עָוׂן וּמְדֻבָּקִים בְּיִרְאָתֶךָ.\nוְחָנֵּנוּ מֵאִתְּךָ דֵּעָה בִּינָה וְהַשְׂכֵּל.","cond":["chonantanu"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, חוֹנֵן הַדָּעַת.","cond":[]},{"kind":"text","text":"הֲשִׁיבֵנוּ אָבִינוּ לְתוֹרָתֶךָ, וְקָרְבֵנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶך, וְהַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ. בָּרוּךְ אַתָּה יהוה, הָרוֹצֶה בִּתְשׁוּבָה.","cond":[]},{"kind":"text","text":"סְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ, כִּי מוֹחֵל וְסוֹלֵחַ אָתָּה. בָּרוּךְ אַתָּה יהוה, חַנּוּן הַמַּרְבֶּה לִסְלֹחַ.","cond":[]},{"kind":"text","text":"רְאֵה בְעָנְיֵנוּ וְרִיבָה רִיבֵנוּ, וּגְאָלֵנוּ מְהֵרָה לְמַעַן שְׁמֶךָ, כִּי גוֹאֵל חָזָק אָתָּה. בָּרוּךְ אַתָּה יהוה, גּוֹאֵל יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"רְפָאֵנוּ יהוה וְנֵרָפֵא, הוֹשִׁיעֵנוּ וְנִוָּשֵׁעָה כִּי תְהִלָּתֵנוּ אָתָּה, וְהַעֲלֵה רְפוּאָה שְׁלֵמָה לְכָל מַכּוֹתֵינוּ.","cond":[]},{"kind":"special","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁתִּשְׁלַח מְהֵרָה רְפוּאָה שְׁלֵמָה מִן הַשָּׁמַיִם, רְפוּאַת הַנֶּפֶשׁ וּרְפוּאַת הַגּוּף לַחוֹלֶה (לנקבה: לַחוֹלָה, לרבים: לַחוֹלִים, לרבות: לַחוֹלוֹת):\n:=:=\nבְּתוֹךְ שְׁאָר חוֹלֵי יִשְׂרָאֵל.","cond":["doctor"]},{"kind":"text","text":"כִּי אֵל מֶלֶךְ רוֹפֵא נֶאֱמָן וְרַחֲמָן אָתָּה. בָּרוּךְ אַתָּה יהוה, רוֹפֵא חוֹלֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"בָּרֵך עָלֵינוּ יהוה אֱלֹהֵינוּ אֶת הַשָּׁנָה הַזֹּאת וְאֶת כָּל מִינֵי תְבוּאָתָהּ לְטוֹבָה, וְתֵן","cond":[]},{"kind":"summer","text":"בְּרָכָה","cond":["summerBracha"]},{"kind":"winter","text":"טַל וּמָטָר לִבְרָכָה","cond":["winterBracha"]},{"kind":"text","text":"עַל פְּנֵי הָאֲדָמָה וְשַׂבְּעֵנוּ מִטּוּבָהּ, וּבָרֵךְ שְׁנָתֵנוּ כַּשָּׁנִים הַטּוֹבוֹת. בָּרוּךְ אַתָּה יהוה, מְבָרֵךְ הַשָּׁנִים.","cond":[]},{"kind":"text","text":"תְּקַע בְּשׁוֹפָר גָּדוֹל לְחֵרוּתֵנוּ, וְשָׂא נֵס לְקַבֵּץ גָּלֻיּוֹתֵינוּ, וְקַבְּצֵנוּ יַחַד מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ. בָּרוּךְ אַתָּה יהוה, מְקַבֵּץ נִדְחֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"הָשִׁיבָה שׁוֹפְטֵינוּ כְּבָרִאשׁוֹנָה וְיוֹעֲצֵינוּ כְּבַתְּחִלָּה, וְהָסֵר מִמֶּנּוּ יָגוֹן וַאֲנָחָה, וּמְלֹךְ עָלֵינוּ אַתָּה יהוה לְבַדְּךָ בְּחֶסֶד וּבְרַחֲמִים, וְצַדְּקֵנוּ בַּמִּשְׁפָט.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, מֶלֶךְ אוֹהֵב צְדָקָה וּמִשְׁפָּט.","cond":["noayt"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יהוה, הַמֶּלֶךְ הַמִּשְׁפָּט.","cond":["ayt"]},{"kind":"text","text":"וְלַמַּלְשִׁינִים אַל תְּהִי תִקְוָה, וְכָל הָרִשְׁעָה כְּרֶגַע תֹּאבֵד, וְכָל אוֹיְבֵי עַמְּךָ מְהֵרָה יִכָּרֵתוּ, וְהַזֵּדִים מְהֵרָה תְעַקֵּר וּתְשַׁבֵּר וּתְמַגֵּר וְתַכְנִיעַ בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יהוה, שׁוֹבֵר אוֹיְבִים וּמַכְנִיעַ זֵדִים.","cond":[]},{"kind":"text","text":"עַל הַצַּדִּיקִים וְעַל הַחֲסִידִים, וְעַל זִקְנֵי עַמְּךָ בֵּית יִשְׂרָאֵל, וְעַל פְּלֵיטַת סוֹפרֵיהֶם, וְעַל גֵּרֵי הַצֶּדֶק וְעָלֵינוּ, יֶהֱמוּ רַחֲמֶיךָ יהוה אֱלֹהֵינוּ, וְתֵן שָׂכָר טוֹב לְכָל הַבּוֹטְחִים בְּשִׁמְךָ בֶּאֱמֶת, וְשִׂים חֶלְקֵנוּ עִמָּהֶם לְעוֹלָם וְלֹא נֵבוֹשׁ כִּי בְךָ בָטָחְנוּ. בָּרוּךְ אַתָּה יהוה, מִשְׁעָן וּמִבְטָח לַצַּדִּיקִים.","cond":[]},{"kind":"text","text":"וְלִירוּשָׁלַיִם עִירְךָ בְּרַחֲמִים תָּשׁוּב וְתִשְׁכֹּן בְּתוֹכָהּ כַּאֲשֶׁר דִּבַּרְתָּ, וּבְנֵה אוֹתָהּ בְּקָרוֹב בְּיָמֵינוּ בִּנְיָן עוֹלָם, וְכִסֵּא דָוִד מְהֵרָה לְתוֹכָהּ תָּכִין. בָּרוּךְ אַתָּה יהוה, בּוֹנֵה יְרוּשָׁלָיִם.","cond":[]},{"kind":"text","text":"אֶת צֶמַח דָּוִד עַבְדְּךָ מְהֵרָה תַצְמִיחַ, וְקַרְנוֹ תָּרוּם בִּישׁוּעָתֶךָ, כִּי לִישׁוּעָתְךָ קִוִּינוּ כָּל הַיּוֹם. בָּרוּךְ אַתָּה יהוה, מַצְמִיחַ קֶרֶן יְשׁוּעָה.","cond":[]},{"kind":"text","text":"שְׁמַע קוֹלֵנוּ יהוה אֱלֹהֵינוּ, חוּס וְרַחֵם עָלֵינוּ, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ, כִּי אֵל שׁוֹמֵעַ תְּפִלּוֹת וְתַחֲנוּנִים אָתָּה, וּמִלְּפָנֶיךָ מַלְכֵּנוּ, רֵיקָם אַל תְּשִׁיבֵנוּ.","cond":[]},{"kind":"special","text":"וַעֲנֵנוּ בּוֹרֵא עוֹלָם בְּמִדַּת הָרַחֲמִים, בּוֹחֵר בְּעַמּוֹ יִשְׂרָאֵל לְהוֹדִיעַ גָדְלוֹ וְהַדְרַת כְּבוֹדוֹ, שׁוֹמֵעַ תְּפִלָּה תֵּן טַל וּמָטָר עַל פְּנֵי הָאֲדָמָה, וְתַשְׂבִּיעַ אֶת הָעוֹלָם כֻּלּוֹ מִטּוּבֶךָ, וּמַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ וּמֵעֹשֶׁר מַתְּנַת יָדֶךָ, שְׁמוֹר וְהַצֵּל שָׁנָה זוֹ מִכָּל דָּבָר רָע, וּמִכָּל מִינִי מַשְׁחִית, וּמִכָּל מִינֵי פֻּרְעָנֻיּוֹת, וַעֲשֵׂה לָהּ תִּקְוָה וְאַחֲרִית שָׁלוֹם, חוּס וְרַחֵם עָלֵינוּ וְעַל כָּל תְּבוּאָתֵנוּ וּפֵרוֹתֵינוּ, וּבָרְכֵנוּ בְּגִשְׁמֵי בְרָכָה וְנִזְכֶּה לְחַיִּים וָשֹׂבַע וְשָׁלוֹם, כַּשָּׁנִים הַטּוֹבוֹת, וְהָסֵר מִמֶּנּוּ דֶּבֶר וְחֶרֶב וְרָעָב, וְחַיָּה רָעָה וּשְׁבִי וּבִזָּה, וְיֵצֶר הָרָע וָחֳלָיִם רָעִים וְקָשִׁים, וּמְאוֹרָעוֹת רָעִים וְקָשִׁים, וּגְזֹר עָלֵינוּ גְּזֵרוֹת טוֹבוֹת מִלְּפָנֶיךָ, וְיִגֹּלוּ רָחֲמֶיךָ עַל מִדּוֹתֶיךָ, וְתִתְנַהֵג עִם בָּנֶיךָ בְּמִדַּת הָרַחֲמִים, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ.","cond":["vaanenu"]},{"kind":"text","text":"כִּי אַתָּה שׁוֹמֵעַ תְּפִלַּת עַמְּךָ יִשְׂרָאֵל בְּרַחֲמִים. בָּרוּךְ אַתָּה יהוה, שׁוֹמֵעַ תְּפִלָּה.","cond":[]},{"kind":"text","text":"רְצֵה יהוה אֱלֹהֵינוּ בְּעַמְּךָ יִשְׂרָאֵל וּבִתְפִלָּתָם, וְהָשֵׁב אֶת הָעֲבוֹדָה לִדְבִיר בֵּיתֶךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם, בְּאַהֲבָה תְקַבֵּל בְּרָצוֹן. וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּךָ.","cond":[]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וּפִקְדוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךָ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים, לְחַיִּים וּלְשָׁלוֹם בְּיוֹם","cond":["rh"]},{"kind":"special","text":"רֹאשׁ הַחֹדֶשׁ הַזֶּה.","cond":["rh"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["rh"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וּפִקְדוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךָ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים, לְחַיִּים וּלְשָׁלוֹם בְּיוֹם","cond":["sucot"]},{"kind":"special","text":"חַג הַסֻּכּוֹת הַזֶּה.","cond":["sucot"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["sucot"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וּפִקְדוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךָ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים, לְחַיִּים וּלְשָׁלוֹם בְּיוֹם","cond":["pesach"]},{"kind":"special","text":"חַג הַמַּצּוֹת הַזֶּה.","cond":["pesach"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["pesach"]},{"kind":"text","text":"וְתֶחֱזֶינָה עֵינֵינוּ בְּשׁוּבְךָ לְצִיּוֹן בְּרַחֲמִים. בָּרוּךְ אַתָּה יהוה, הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן.","cond":[]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שָׁאַתָּה הוּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ לְעוֹלָם וָעֶד. צוּר חַיֵּינוּ, מָגֵן יִשְׁעֵנוּ אַתָּה הוּא לְדוֹר וָדוֹר. נוֹדֶה לְּךָ וּנְסַפֵּר תְּהִלָּתֶךָ עַל חַיֵּינוּ הַמְּסוּרִים בְּיָדֶךָ, וְעַל נִשְׁמוֹתֵינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּיךָ שֶׁבְּכָל יוֹם עִמָּנוּ, וְעַל נִפְלְאוֹתֶיךָ וְטוֹבוֹתֶיךָ שֶׁבְּכָל עֵת, עֶרֶב וָבֹקֶר וְצָהֳרָיִם. הַטּוֹב כִּי לֹא כָלוּ רַחֲמֶיךָ, וְהַמְרַחֵם כִּי לֹא תַמּוּ חֲסָדֶיךָ. מֵעוֹלָם קִוִּינוּ לָךְ.","cond":[]},{"kind":"special","text":"עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מַתִּתְיָהוּ בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְהַשְׁכִּיחָם תּוֹרָתֶךָ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנֶךָ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּטְמֵאִים בְּיַד טְהוֹרִים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, וּלְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמֶךָ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כֵּן בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ לְהוֹדוֹת וּלְהַלֵּל לְשִׁמְךָ הַגָּדוֹל.","cond":["chanuka"]},{"kind":"special","text":"עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים, מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ, וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ, וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְּרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ (, וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה).","cond":["purim"]},{"kind":"text","text":"וְעַל כֻּלָּם יִתְבָּרַךְ וְיִתְרוֹמַם שִׁמְךָ מַלְכֵּנוּ תָּמִיד לְעוֹלָם וָעֶד.","cond":[]},{"kind":"special","text":"וּכְתֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶךָ.","cond":["ayt"]},{"kind":"text","text":"וְכֹל הַחַיִּים יוֹדוּךָ סֶּלָה, וִיהַלְלוּ אֶת שִׁמְךָ בֶּאֱמֶת, הָאֵל יְשׁוּעָתֵנוּ וְעֶזְרָתֵנוּ סֶלָה. בָּרוּך אַתָּה יהוה, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת.","cond":[]},{"kind":"text","text":"שָׁלוֹם רָב עַל יִשְׂרָאֵל עַמְּךָ תָּשִׂים לְעוֹלָם, כִּי אַתָּה הוּא מֶלֶךְ אָדוֹן לְכָל הַשָּלוֹם, וְטוֹב בְּעֵינֶיךָ לְבָרֵךְ אֶת עַמְּךָ יִשְׂרָאֵל בְּכָל עֵת וּבְכָל שָׁעָה בִּשְׁלוֹמֶךָ.","cond":[]},{"kind":"special","text":"בְּסֵפֶר חַיִּים, בְּרָכָה וְשָׁלוֹם, וּפַרְנָסָה טוֹבָה, נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ, אֲנַחְנוּ וְכָל עַמְּךָ בֵּית יִשְׂרָאֵל, לְחַיִּים טוֹבִים וּלְשָׁלוֹם.","cond":["ayt"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הַמְבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם.","cond":[]},{"kind":"text","text":"יִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:\nאֱלֹהַי, נְצֹר לְשׁוֹנִי מֵרָע וּשְׂפָתַי מִדַּבֵּר מִרְמָה, וְלִמְקַלְלַי נַפְשִׁי תִדֹּם, וְנַפְשִׁי כֶּעָפָר לַכֹּל תִּהְיֶה. פְּתַח לִבִּי בְּתוֹרָתֶךָ, וּבְמִצְוׂתֶיךָ תִּרְדֹף נַפְשִׁי. וְכָל הַחוֹשְׁבִים עָלַי רָעָה, מְהֵרָה הָפֵר עֲצָתָם וְקַלְקֵל מַחֲשַׁבְתָּם. עֲשֵׂה לְמַעַן שְׁמֶךָ, עֲשֵׂה לְמַעַן יְמִינֶךָ, עֲשֵׂה לְמַעַן קְדֻשָּׁתֶךָ, עֲשֵׂה לְמַעַן תּוֹרָתֶךָ. לְמַעַן יֵחָלְצוּן יְדִידֶיךָ הוֹשִׁיעָה יְמִינְךָ וַעֲנֵנִי:\nיִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:","cond":[]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁיִּבָּנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵינוּ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתֶךָ, וְשָׁם נַעֲבָדְךָ בְּיִרְאָה כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמוֹנִיּוֹת. וְעָרְבָה לַיהוה מִנְחַת יְהוּדָה וִירוּשָׁלָיִם כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמֹנִיּוֹת:","cond":[]},{"kind":"instruction","text":"חצי קדיש","cond":["kadosh"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":["kadosh"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["kadosh","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["kadosh","ayt"]},{"kind":"header","text":"ויהי נעם","cond":["kadosh","sun"]},{"kind":"text","text":"וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ: יֹשֵׁב בְּסֵתֶר עֶלְיוֹן בְּצֵל שַׁדַּי יִתְלוֹנָן: אֹמַר לַיהוה מַחְסִי וּמְצוּדָתִי, אֱלֹהַי אֶבְטַח בּוֹ: כִּי הוּא יַצִּילְךָ מִפַּח יָקוּשׁ מִדֶּבֶר הַוּוֹת: בְּאֶבְרָתוֹ יָסֶךְ לָךְ וְתַחַת כְּנָפָיו תֶּחְסֶה, צִנָּה וְסֹחֵרָה אֲמִתּוֹ: לֹא תִירָא מִפַּחַד לָיְלָה, מֵחֵץ יָעוּף יוֹמָם: מִדֶּבֶר בָּאֹפֶל יַהֲלֹךְ, מִקֶּטֶב יָשׁוּד צָהֳרָיִם: יִפֹּל מִצִּדְּךָ אֶלֶף וּרְבָבָה מִימִינֶךָ, אֵלֶיךָ לֹא יִגָּשׁ: רַק בְּעֵינֶיךָ תַבִּיט, וְשִׁלֻּמַת רְשָׁעִים תִּרְאֶה: כִּי אַתָּה יהוה מַחְסִי, עֶלְיוֹן שַׂמְתָּ מְעוֹנֶךָ: לֹא תְאֻנֶּה אֵלֶיךָ רָעָה, וְנֶגַע לֹא יִקְרַב בְּאָהֳלֶךָ: כִּי מַלְאָכָיו יְצַוֶּה לָּךְ, לִשְׁמָרְךָ בְּכָל דְּרָכֶיךָ: עַל כַּפַּיִם יִשָּׂאוּנְךָ, פֶּן תִּגֹּף בָּאֶבֶן רַגְלֶךָ: עַל שַׁחַל וָפֶתֶן תִּדְרֹךְ, תִּרְמֹס כְּפִיר וְתַנִּין: כִּי בִי חָשַׁק וַאֲפַלְּטֵהוּ, אֲשַׂגְּבֵהוּ כִּי יָדַע שְׁמִי: יִקְרָאֵנִי וְאֶעֱנֵהוּ, עִמּוֹ אָנֹכִי בְצָרָה, אֲחַלְּצֵהוּ וַאֲכַבְּדֵהוּ: אֹרֶךְ יָמִים אַשְׂבִּיעֵהוּ, וְאַרְאֵהוּ בִּישׁוּעָתִי: אֹרֶךְ יָמִים אַשְׂבִּיעֵהוּ, וְאַרְאֵהוּ בִּישׁוּעָתִי:","cond":["kadosh","sun"]},{"kind":"header","text":"ואתה קדוש","cond":["kadosh"]},{"kind":"text","text":"וְאַתָּה קָדוֹשׁ יוֹשֵׁב תְּהִלּוֹת יִשְׂרָאֵל: וְקָרָא זֶה אֶל זֶה וְאָמַר: קָדוֹשׁ, קָדוֹשׁ, קָדוֹשׁ יהוה צְבָאוֹת, מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ: וּמְקַבְּלִין דֵּין מִן דֵּין וְאָמְרִין: קַדִּישׁ בִּשְׁמֵי מֵרוֹמַא עִלָאַה בֵּית שְׁכִינְתֵּהּ, קַדִּישׁ עַל אַרְעָא עוֹבַד גְּבוּרְתֵּהּ, קַדִּישׁ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא, יהוה צְבָאוֹת מַלְיָא כָל אַרְעָא זִיו יְקָרֵהּ. וַתִּשָּׂאֵנִי רוּחַ, וָאֶשְׁמַע אַחֲרַי קוֹל רַעַשׁ גָּדוֹל: בָּרוּךְ כְּבוֹד יהוה מִמְּקוֹמוֹ: וּנְטָלַתְנִי רוּחָא, וּשְׁמָעִית בַּתְרַי קַל זִיעַ שַׂגִּיא דִמְשַׁבְּחִין וְאָמְרִין: בְּרִיךְ יְקָרָא דַיהוה מֵאֲתָר בֵּית שְׁכִינְתֵּהּ. יהוה יִמְלֹךְ לְעוֹלָם וָעֶד: יהוה מַלְכוּתֵיהּ קָאֵים לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\n\nיהוה אֱלֹהֵי אַבְרָהָם יִצְחָק וְיִשְׂרָאֵל אֲבוֹתֵינוּ, שָׁמְרָה זֹּאת לְעוֹלָם, לְיֵצֶר מַחְשְׁבוֹת לְבַב עַמֶּךָ, וְהָכֵן לְבָבָם אֵלֶיךָ: וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית, וְהִרְבָּה לְהָשִׁיב אַפּוֹ, וְלֹא יָעִיר כָּל חֲמָתוֹ: כִּי אַתָּה יהוה טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קוֹרְאֶיךָ: צִדְקָתְךָ צֶּדֶק לְעוֹלָם, וְתוֹרָתְךָ אֱמֶת: תִּתֵּן אֱמֶת לְיַעֲקֹב, חֶסֶד לְאַבְרָהָם, אֲשֶׁר נִשְׁבַּעְתָּ לַאֲבֹתֵינוּ מִימֵי קֶדֶם: בָּרוּךְ אֲדֹנָי יוֹם יוֹם, יַעֲמָס לָנוּ הָאֵל יְשׁוּעָתֵנוּ, סֶלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב, סֶלָה: יהוה צְבָאוֹת אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ: בָּרוּךְ הוּא אֱלֹהֵינוּ שֶׁבְּרָאָנוּ לִכְבוֹדוֹ, וְהִבְדִּילָנוּ מִן הַתּוֹעִים, וְנָתַן לָנוּ תּוֹרַת אֱמֶת, וְחַיֵּי עוֹלָם נָטַע בְּתוֹכֵנוּ. הוּא יִפְתַּח לִבֵּנוּ בְּתוֹרָתוֹ, וְיָשֵׂם בְּלִבֵּנוּ אַהֲבָתוֹ וְיִרְאָתוֹ וְלַעֲשׂוֹת רְצוֹנוֹ וּלְעָבְדוֹ בְּלֵבָב שָׁלֵם. לְמַעַן לֹא נִיגַע לָרִיק, וְלֹא נֵלֵד לַבֶּהָלָה. יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁנִּשְׁמֹר חֻקֶּיךָ בָּעוֹלָם הַזֶּה, וְנִזְכֶּה וְנִחְיֶה וְנִרְאֶה וְנִירַשׁ טוֹבָה וּבְרָכָה לִשְׁנֵי יְמוֹת הַמָּשִׁיחַ וּלְחַיֵּי הָעוֹלָם הַבָּא. לְמַעַן יְזַמֶּרְךָ כָבוֹד וְלֹא יִדֹּם, יהוה אֱלֹהַי לְעוֹלָם אוֹדֶךָּ: בָּרוּךְ הַגֶּבֶר אֲשֶׁר יִבְטַח בַּיהוה, וְהָיָה יהוה מִבְטַחוֹ: בִּטְחוּ בַיהוה עֲדֵי עַד, כִּי בְּיָהּ יהוה צוּר עוֹלָמִים: וְיִבְטְחוּ בְךָ יוֹדְעֵי שְׁמֶךָ, כִּי לֹא עָזַבְתָּ דֹּרְשֶׁיךָ יהוה: יהוה חָפֵץ לְמַעַן צִדְקוֹ, יַגְדִּיל תּורָה וְיַאְדִּיר:","cond":["kadosh"]},{"kind":"instruction","text":"קדיש תתקבל","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":[]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"תִּתְקַבַּל צְלוֹתְהוֹן וּבָעוּתְהוֹן דְּכָל יִשְׂרָאֵל קֳדָם אֲבוּהוֹן דִּי בִשְׁמַיָּא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"header","text":"המשך תפילת יום העצמאות","cond":["yerushalayim"]},{"kind":"instruction","text":"פותחים את הארון\n\nהש\"ץ אומר והקהל עונה אחריו:","cond":["yerushalayim"]},{"kind":"text","text":"שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:\n\nיהוה הוּא הָאֱלֹהִים: יהוה הוּא הָאֱלֹהִים: יהוה הוּא הָאֱלֹהִים:","cond":["yerushalayim"]},{"kind":"instruction","text":"הש\"ץ אומר והקהל חוזר אחריו:","cond":["yerushalayim"]},{"kind":"text","text":"מִי שֶׁעָשָׂה נִסִּים לַאֲבוֹתֵינוּ וְלָנוּ וּגְאָלָנוּ מֵעַבְדּוּת לְחֵרוּת, הוּא יִגְאָלֵנוּ גְאֻלָּה שְׁלֵמָה בְּקָרוֹב, וִיקַבֵּץ נִדָּחֵינוּ מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ, חֲבֵרִים כָּל יִשְׂרָאֵל, וְנֹאמַר אָמֵן.","cond":["yerushalayim"]},{"kind":"instruction","text":"הש\"ץ אומר:","cond":["yerushalayim"]},{"kind":"text","text":"וְכִי-תָבֹאוּ מִלְחָמָה בְּאַרְצְכֶם, עַל-הַצַּר הַצֹּרֵר אֶתְכֶם, וַהֲרֵעֹתֶם בַּחֲצֹצְרֹת, וְנִזְכַּרְתֶּם לִפְנֵי יהוה אֱלֹהֵיכֶם וְנוֹשַׁעְתֶּם מֵאֹיְבֵיכֶם: וּבְיוֹם שִׂמְחַתְכֶם וּבְמוֹעֲדֵיכֶם וּבְרָאשֵׁי חָדְשֵׁיכֶם וּתְקַעְתֶּם בַּחֲצֹצְרֹת עַל עֹלֹתֵיכֶם וְעַל זִבְחֵי שַׁלְמֵיכֶם וְהָיוּ לָכֶם לְזִכָּרוֹן לִפְנֵי אֱלֹהֵיכֶם, אֲנִי יהוה אֱלֹהֵיכֶם:","cond":["yerushalayim"]},{"kind":"instruction","text":"תוקעים תקיעה גדולה ואומרים בקול רם:","cond":["yerushalayim"]},{"kind":"text","text":"לַשָּׁנָה הַבָּאָה בִּירוּשָׁלַיִם הַבְּנוּיָה.","cond":["yerushalayim"]},{"kind":"instruction","text":"(כל הקהל אומר","cond":["yerushalayim"]},{"kind":"text","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁכְּשֵׁם שֶׁזָּכִינוּ לְאַתְחַלְתָּא דִגְאֻלָּה, כֵּן נִזְכֶּה לִשְׁמֹעַ קוֹל שׁוֹפָרוֹ שֶׁל מָשִׁיחַ בִּמְהֵרָה בְיָמֵינוּ.)","cond":["yerushalayim"]},{"kind":"instruction","text":"ושרים במנגינת התקוה:","cond":["yerushalayim"]},{"kind":"text","text":"שִׁיר הַמַּעֲלוֹת בְּשׁוּב יהוה אֶת שִׁיבַת צִיּוֹן, הָיִינוּ כְּחֹלְמִים: אָז יִמָּלֵא שְׂחוֹק פִּינוּ וּלְשׁוֹנֵנוּ רִנָּה, אָז יֹאמְרוּ בַגּוֹיִם הִגְדִּיל יהוה לַעֲשׂוֹת עִם אֵלֶּה: הִגְדִּיל יהוה לַעֲשׂוֹת עִמָּנוּ, הָיִינוּ שְׂמֵחִים: שׁוּבָה יהוה אֶת שְׁבִיתֵנוּ כַּאֲפִיקִים בַּנֶּגֶב: הַזֹּרְעִים בְּדִמְעָה בְּרִנָּה יִקְצֹרוּ: הָלוֹךְ יֵלֵךְ וּבָכֹה נֹשֵׂא מֶשֶׁךְ הַזָּרַע, בֹּא יָבוֹא בְרִנָּה נֹשֵׂא אֲלֻמֹּתָיו:","cond":["yerushalayim"]},{"kind":"header","text":"ספירת העומר","cond":["omer"]},{"kind":"instruction","text":"ספירת העומר","cond":["omer"]},{"kind":"text","text":"לְשֵׁם יִחוּד קֻדְשָׁא בְּרִיךְ הוּא וּשְׁכִינְתֵּיהּ בִּדְחִילוּ וּרְחִימוּ, לְיַחֵד שֵׁם י\"ה בְּו\"ה בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל יִשְׂרָאֵל, הִנְנִי מוּכָן וּמְזֻמָּן לְקַיֵּם מִצְוַת עֲשֵׂה שֶׁל סְפִירַת הָעֹמֶר, כְּמו שֶׁכָּתוּב בַּתּוֹרָה: וּסְפַרְתֶּם לָכֶם מִמָּחֳרַת הַשַּׁבָּת, מִיוֹם הֲבִיאֲכֶם אֶת עֹמֶר הַתְּנוּפָה, שֶׁבַע שַׁבָּתוֹת תְּמִימוֹת תִּהְיֶינָה: עַד מִמָּחֳרַת הַשַּׁבָּת הַשְּׁבִיעִית תִּסְפְּרוּ חֲמִשִּׁים יוֹם, וְהִקְרַבְתֶּם מִנְחָה חֲדָשָׁה לַיהוה: וִיהִי נֹעַם יהוה אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ:\n\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ עַל סְפִירַת הָעֹמֶר.\n\n::::\n\nהָרַחֲמָן הוּא יַחֲזִיר לָנוּ עֲבוֹדַת בֵּית הַמִּקְדָּשׁ לִמְקוֹמָהּ בִּמְהֵרָה בְיָמֵינוּ. אָמֵן סֶלָה.","cond":["omer"]},{"kind":"text","text":"לַמְנַצֵּחַ בִּנְגִינֹת מִזְמוֹר שִׁיר: אֱלֹהִים יְחָנֵּנוּ וִיבָרְכֵנוּ, יָאֵר פָּנָיו אִתָּנוּ סֶלָה: לָדַעַת בָּאָרֶץ דַּרְכֶּךָ, בְּכָל-גּוֹיִם יְשׁוּעָתֶךָ: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: יִשְׂמְחוּ וִירַנְּנוּ לְאֻמִּים כִּי-תִשְׁפֹּט עַמִּים מִישֹׁר, וּלְאֻמִּים בָּאָרֶץ תַּנְחֵם סֶלָה: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: אֶרֶץ נָתְנָה יְבוּלָהּ, יְבָרְכֵנוּ אֱלֹהִים אֱלֹהֵינוּ: יְבָרְכֵנוּ אֱלֹהִים, וְיִירְאוּ אוֹתוֹ כָּל-אַפְסֵי-אָרֶץ:","cond":["omer"]},{"kind":"text","text":"אָנָּא, בְּכֹחַ גְּדֻלַּת יְמִינְךָ, תַּתִּיר צְרוּרָה (אב\"ג ית\"ץ).","cond":["omer"]},{"kind":"text","text":"קַבֵּל רִנַּת עַמְּךָ, שַׂגְּבֵנוּ, טַהֲרֵנוּ, נוֹרָא (קר\"ע שט\"ן).","cond":["omer"]},{"kind":"text","text":"נָא גִּבּוֹר, דּוֹרְשֵׁי יִחוּדֶךָ, כְּבָבַת שָׁמְרֵם (נג\"ד יכ\"ש).","cond":["omer"]},{"kind":"text","text":"בָּרְכֵם, טַהֲרֵם, רַחֲמֵי צִדְקָתְךָ תָּמִיד גָּמְלֵם (בט\"ר צת\"ג).","cond":["omer"]},{"kind":"text","text":"חָסִין קָדוֹשׁ, בְּרֹב טוּבְךָ נַהֵל עֲדָתֶךָ (חק\"ב טנ\"ע).","cond":["omer"]},{"kind":"text","text":"יָחִיד גֵּאֶה, לְעַמְּךָ פְנֵה, זוֹכְרֵי קְדֻשָּׁתֶךָ (יג\"ל פז\"ק).","cond":["omer"]},{"kind":"text","text":"שַׁוְעָתֵנוּ קַבֵּל, וּשְׁמַע צַעֲקָתֵנוּ, יוֹדֵעַ תַּעֲלוּמוֹת (שק\"ו צי\"ת).","cond":["omer"]},{"kind":"text","text":"בלחש - בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֵד.\n\nרִבּוֹנוֹ שֶׁל עוֹלָם, אַתָּה צִוִּיתָנוּ עַל יְדֵי מֹשֶׁה עַבְדְּךָ לִסְפֹּר סְפִירַת הָעֹמֶר כְּדֵי לְטַהֲרֵנוּ מִקְּלִפּוֹתֵינוּ וּמִטֻּמְאוֹתֵינוּ, כְּמוֹ שֶׁכָּתַבְתָּ בְּתוֹרָתֶךָ: וּסְפַרְתֶּם לָכֶם מִמָּחֳרַת הַשַּׁבָּת, מִיוֹם הֲבִיאֲכֶם אֶת עֹמֶר הַתְּנוּפָה, שֶׁבַע שַׁבָּתוֹת תְּמִימוֹת תִּהְיֶינָה: עַד מִמָּחֳרַת הַשַּׁבָּת הַשְּׁבִיעִית תִּסְפְּרוּ חֲמִשִּׁים יוֹם, כְּדֵי שֶׁיִּטָּהֲרוּ נַפְשׁוֹת עַמְּךָ יִשְׂרָאֵל מִזֻּהֲמָתָם. וּבְכֵן יְהִי רָצוֹן מִלְּפָנֶיךָ, יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁבִּזְכוּת סְפִירַת הָעֹמֶר שֶׁסָּפַרְתִּי הַיּוֹם, יְתֻקַּן מַה שֶׁפָּגַמְתִּי בִּסְפִירָה\n:::\nוְאֶטָּהֵר וְאֶתְקַדֵּשׁ בִּקְדֻשָּׁה שֶׁל מַעְלָה, וְעַל יְדֵי זֶה יֻשְׁפַּע שֶׁפַע רַב בְּכָל הָעוֹלָמוֹת לְתַקֵּן אֶת נַפְשׁוֹתֵינוּ וְרוּחוֹתֵינוּ וְנִשְׁמוֹתֵינוּ מִכָּל סִיג וּפְגַם, וּלְטַהֲרֵנוּ וּלְקַדְּשֵׁנוּ בִּקְדֻשָּׁתְךָ הָעֶלְיוֹנָה, אָמֵן סֶלָה.","cond":["omer"]},{"kind":"instruction","text":"מברך לאור הנר:","cond":["tishaaBeav","sun"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא מְאוֹרֵי הָאֵשׁ.","cond":["tishaaBeav","sun"]},{"kind":"header","text":"מגילת איכה","cond":["tishaaBeav"]},{"kind":"instruction","text":"מגילת איכה\n\n\nפרק א'","cond":["tishaaBeav"]},{"kind":"text","text":"אֵיכָה יָשְׁבָה בָדָד הָעִיר רַבָּתִי עָם הָיְתָה כְּאַלְמָנָה, רַבָּתִי בַגּוֹיִם, שָׂרָתִי בַּמְּדִינוֹת, הָיְתָה לָמַס: בָּכוֹ תִבְכֶּה בַּלַּיְלָה וְדִמְעָתָהּ עַל לֶחֱיָהּ, אֵין לָהּ מְנַחֵם מִכָּל אֹהֲבֶיהָ, כָּל רֵעֶיהָ בָּגְדוּ בָהּ, הָיוּ לָהּ לְאֹיְבִים: גָּלְתָה יְהוּדָה מֵעֹנִי וּמֵרֹב עֲבֹדָה, הִיא יָשְׁבָה בַגּוֹיִם, לֹא מָצְאָה מָנוֹחַ, כָּל רֹדְפֶיהָ הִשִּׂיגוּהָ בֵּין הַמְּצָרִים: דַּרְכֵי צִיּוֹן אֲבֵלוֹת מִבְּלִי בָּאֵי מוֹעֵד, כָּל שְׁעָרֶיהָ שׁוֹמֵמִין, כֹּהֲנֶיהָ נֶאֱנָחִים, בְּתוּלֹתֶיהָ נּוּגוֹת וְהִיא מַר לָהּ: הָיוּ צָרֶיהָ לְרֹאשׁ אֹיְבֶיהָ שָׁלוּ, כִּי יהוה הוֹגָהּ עַל רֹב פְּשָׁעֶיהָ, עוֹלָלֶיהָ הָלְכוּ שְׁבִי לִפְנֵי צָר: וַיֵּצֵא מִבַּת צִיּוֹן כָּל הֲדָרָהּ, הָיוּ שָׂרֶיהָ כְּאַיָּלִים לֹא מָצְאוּ מִרְעֶה, וַיֵּלְכוּ בְלֹא כֹחַ לִפְנֵי רוֹדֵף: זָכְרָה יְרוּשָׁלַיִם יְמֵי עָנְיָהּ וּמְרוּדֶיהָ, כֹּל מַחֲמֻדֶיהָ אֲשֶׁר הָיוּ מִימֵי קֶדֶם, בִּנְפֹל עַמָּהּ בְּיַד צָר וְאֵין עוֹזֵר לָהּ, רָאוּהָ צָרִים, שָׂחֲקוּ עַל מִשְׁבַּתֶּהָ: חֵטְא חָטְאָה יְרוּשָׁלַיִם, עַל כֵּן לְנִידָה הָיָתָה, כָּל מְכַבְּדֶיהָ הִזִּילוּהָ כִּי רָאוּ עֶרְוָתָהּ, גַּם הִיא נֶאֶנְחָה וַתָּשָׁב אָחוֹר: טֻמְאָתָהּ בְּשׁוּלֶיהָ, לֹא זָכְרָה אַחֲרִיתָהּ, וַתֵּרֶד פְּלָאִים, אֵין מְנַחֵם לָהּ, רְאֵה יהוה אֶת עָנְיִי כִּי הִגְדִּיל אוֹיֵב: יָדוֹ פָּרַשׂ צָר עַל כָּל מַחֲמַדֶּיהָ, כִּי רָאֲתָה גוֹיִם בָּאוּ מִקְדָּשָׁהּ, אֲשֶׁר צִוִּיתָה לֹא יָבֹאוּ בַקָּהָל לָךְ: כָּל עַמָּהּ נֶאֱנָחִים מְבַקְשִׁים לֶחֶם, נָתְנוּ מַחֲמַדֵּיהֶם בְּאֹכֶל לְהָשִׁיב נָפֶשׁ, רְאֵה יהוה וְהַבִּיטָה כִּי הָיִיתִי זוֹלֵלָה: לוֹא אֲלֵיכֶם כָּל עֹבְרֵי דֶרֶךְ, הַבִּיטוּ וּרְאוּ אִם יֵשׁ מַכְאוֹב כְּמַכְאֹבִי אֲשֶׁר עוֹלַל לִי, אֲשֶׁר הוֹגָה יהוה בְּיוֹם חֲרוֹן אַפּוֹ: מִמָּרוֹם שָׁלַח אֵשׁ בְּעַצְמֹתַי וַיִּרְדֶּנָּה, פָּרַשׂ רֶשֶׁת לְרַגְלַי הֱשִׁיבַנִי אָחוֹר, נְתָנַנִי שֹׁמֵמָה כָּל הַיּוֹם דָּוָה: נִשְׂקַד עֹל פְּשָׁעַי בְּיָדוֹ, יִשְׂתָּרְגוּ, עָלוּ עַל צַוָּארִי הִכְשִׁיל כֹּחִי, נְתָנַנִי אֲדֹנָי בִּידֵי לֹא אוּכַל קוּם: סִלָּה כָל אַבִּירַי אֲדֹנָי בְּקִרְבִּי, קָרָא עָלַי מוֹעֵד לִשְׁבֹּר בַּחוּרָי, גַּת דָּרַךְ אֲדֹנָי לִבְתוּלַת בַּת יְהוּדָה: עַל אֵלֶּה אֲנִי בוֹכִיָּה, עֵינִי עֵינִי יֹרְדָה מַּיִם, כִּי רָחַק מִמֶּנִּי מְנַחֵם מֵשִׁיב נַפְשִׁי, הָיוּ בָנַי שׁוֹמֵמִים כִּי גָבַר אוֹיֵב: פֵּרְשָׂה צִיּוֹן בְּיָדֶיהָ, אֵין מְנַחֵם לָהּ, צִוָּה יהוה לְיַעֲקֹב סְבִיבָיו צָרָיו, הָיְתָה יְרוּשָׁלַיִם לְנִדָּה בֵּינֵיהֶם: צַדִּיק הוּא יהוה כִּי פִיהוּ מָרִיתִי, שִׁמְעוּ נָא כָל הָעַמִּים וּרְאוּ מַכְאֹבִי, בְּתוּלֹתַי וּבַחוּרַי הָלְכוּ בַשֶּׁבִי: קָרָאתִי לַמְאַהֲבַי הֵמָּה רִמּוּנִי, כֹּהֲנַי וּזְקֵנַי בָּעִיר גָּוָעוּ, כִּי בִקְשׁוּ אֹכֶל לָמוֹ וְיָשִׁיבוּ אֶת נַפְשָׁם: רְאֵה יהוה כִּי צַר לִי מֵעַי חֳמַרְמָרוּ, נֶהְפַּךְ לִבִּי בְּקִרְבִּי כִּי מָרוֹ מָרִיתִי, מִחוּץ שִׁכְּלָה חֶרֶב, בַּבַּיִת כַּמָּוֶת: שָׁמְעוּ כִּי נֶאֱנָחָה אָנִי, אֵין מְנַחֵם לִי, כָּל אֹיְבַי שָׁמְעוּ רָעָתִי שָׂשׂוּ כִּי אַתָּה עָשִׂיתָ, הֵבֵאתָ יוֹם קָרָאתָ וְיִהְיוּ כָמוֹנִי: תָּבֹא כָל רָעָתָם לְפָנֶיךָ וְעוֹלֵל לָמוֹ, כַּאֲשֶׁר עוֹלַלְתָּ לִי עַל כָּל פְּשָׁעָי, כִּי רַבּוֹת אַנְחֹתַי וְלִבִּי דַוָּי:","cond":["tishaaBeav"]},{"kind":"instruction","text":"פרק ב'","cond":["tishaaBeav"]},{"kind":"text","text":"אֵיכָה יָעִיב בְּאַפּוֹ אֲדֹנָי אֶת בַּת צִיּוֹן, הִשְׁלִיךְ מִשָּׁמַיִם אֶרֶץ, תִּפְאֶרֶת יִשְׂרָאֵל, וְלֹא זָכַר הֲדֹם רַגְלָיו בְּיוֹם אַפּוֹ: בִּלַּע אֲדֹנָי וְלֹא חָמַל אֵת כָּל נְאוֹת יַעֲקֹב, הָרַס בְּעֶבְרָתוֹ מִבְצְרֵי בַת יְהוּדָה הִגִּיעַ לָאָרֶץ, חִלֵּל מַמְלָכָה וְשָׂרֶיהָ: גָּדַע בָּחֳרִי אַף כֹּל קֶרֶן יִשְׂרָאֵל, הֵשִׁיב אָחוֹר יְמִינוֹ מִפְּנֵי אוֹיֵב, וַיִּבְעַר בְּיַעֲקֹב כְּאֵשׁ לֶהָבָה, אָכְלָה סָבִיב: דָּרַךְ קַשְׁתּוֹ כְּאוֹיֵב, נִצָּב יְמִינוֹ כְּצָר, וַיַּהֲרֹג כֹּל מַחֲמַדֵּי עָיִן, בְּאֹהֶל בַּת צִיּוֹן שָׁפַךְ כָּאֵשׁ חֲמָתוֹ: הָיָה אֲדֹנָי כְּאוֹיֵב, בִּלַּע יִשְׂרָאֵל, בִּלַּע כָּל אַרְמְנוֹתֶיהָ שִׁחֵת מִבְצָרָיו, וַיֶּרֶב בְּבַת יְהוּדָה תַּאֲנִיָּה וַאֲנִיָּה: וַיַּחְמֹס כַּגַּן שֻׂכּוֹ שִׁחֵת מוֹעֲדוֹ, שִׁכַּח יהוה בְּצִיּוֹן מוֹעֵד וְשַׁבָּת, וַיִּנְאַץ בְּזַעַם אַפּוֹ מֶלֶךְ וְכֹהֵן: זָנַח אֲדֹנָי מִזְבְּחוֹ, נִאֵר מִקְדָּשׁוֹ, הִסְגִּיר בְּיַד אוֹיֵב חוֹמֹת אַרְמְנוֹתֶיהָ, קוֹל נָתְנוּ בְּבֵית יהוה כְּיוֹם מוֹעֵד: חָשַׁב יהוה לְהַשְׁחִית חוֹמַת בַּת צִיּוֹן, נָטָה קָו לֹא הֵשִׁיב יָדוֹ מִבַּלֵּעַ, וַיַּאֲבֶל חֵל וְחוֹמָה יַחְדָּו אֻמְלָלוּ: טָבְעוּ בָאָרֶץ שְׁעָרֶיהָ, אִבַּד וְשִׁבַּר בְּרִיחֶיהָ, מַלְכָּהּ וְשָׂרֶיהָ בַגּוֹיִם אֵין תּוֹרָה, גַּם נְבִיאֶיהָ לֹא מָצְאוּ חָזוֹן מֵיהוה: יֵשְׁבוּ לָאָרֶץ יִדְּמוּ זִקְנֵי בַת צִיּוֹן, הֶעֱלוּ עָפָר עַל רֹאשָׁם, חָגְרוּ שַׂקִּים, הוֹרִידוּ לָאָרֶץ רֹאשָׁן בְּתוּלֹת יְרוּשָׁלַיִם: כָּלוּ בַדְּמָעוֹת עֵינַי חֳמַרְמְרוּ מֵעַי, נִשְׁפַּךְ לָאָרֶץ כְּבֵדִי עַל שֶׁבֶר בַּת עַמִּי, בֵּעָטֵף עוֹלֵל וְיוֹנֵק בִּרְחֹבוֹת קִרְיָה: לְאִמֹּתָם יֹאמְרוּ אַיֵּה דָּגָן וָיָיִן, בְּהִתְעַטְּפָם כֶּחָלָל בִּרְחֹבוֹת עִיר, בְּהִשְׁתַּפֵּךְ נַפְשָׁם אֶל חֵיק אִמֹּתָם: מָה אֲעִידֵךְ מָה אֲדַמֶּה לָּךְ, הַבַּת יְרוּשָׁלַיִם, מָה אַשְׁוֶה לָּךְ וַאֲנַחֲמֵךְ בְּתוּלַת בַּת צִיּוֹן, כִּי גָדוֹל כַּיָּם שִׁבְרֵךְ מִי יִרְפָּא לָךְ: נְבִיאַיִךְ חָזוּ לָךְ שָׁוְא וְתָפֵל, וְלֹא גִלּוּ עַל עֲוׂנֵךְ לְהָשִׁיב שְׁבוּתֵךְ, וַיֶּחֱזוּ לָךְ מַשְׂאוֹת שָׁוְא וּמַדּוּחִים: סָפְקוּ עָלַיִךְ כַּפַּיִם כָּל עֹבְרֵי דֶרֶךְ, שָׁרְקוּ וַיָּנִעוּ רֹאשָׁם עַל בַּת יְרוּשָׁלָיִם, הֲזֹאת הָעִיר שֶׁיֹּאמְרוּ כְּלִילַת יֹפִי, מָשׂוֹשׂ לְכָל הָאָרֶץ: פָּצוּ עָלַיִךְ פִּיהֶם כָּל אוֹיְבַיִךְ, שָׁרְקוּ וַיַּחַרְקוּ שֵׁן, אָמְרוּ בִּלָּעְנוּ, אַךְ זֶה הַיּוֹם שֶׁקִּוִּינֻהוּ מָצָאנוּ רָאִינוּ: עָשָׂה יהוה אֲשֶׁר זָמָם, בִּצַּע אֶמְרָתוֹ אֲשֶׁר צִוָּה מִימֵי קֶדֶם, הָרַס וְלֹא חָמָל, וַיְשַׂמַּח עָלַיִךְ אוֹיֵב, הֵרִים קֶרֶן צָרָיִךְ: צָעַק לִבָּם אֶל אֲדֹנָי, חוֹמַת בַּת צִיּוֹן הוֹרִידִי כַנַּחַל דִּמְעָה יוֹמָם וָלַיְלָה, אַל תִּתְּנִי פוּגַת לָךְ, אַל תִּדֹּם בַּת עֵינֵךְ: קוּמִי רֹנִּי בַלַּיְלָה לְרֹאשׁ אַשְׁמֻרוֹת, שִׁפְכִי כַמַּיִם לִבֵּךְ נֹכַח פְּנֵי אֲדֹנָי, שְׂאִי אֵלָיו כַּפַּיִךְ עַל נֶפֶשׁ עוֹלָלַיִךְ הָעֲטוּפִים בְּרָעָב בְּרֹאשׁ כָּל חוּצוֹת: רְאֵה יהוה וְהַבִּיטָה לְמִי עוֹלַלְתָּ כֹּה, אִם תֹּאכַלְנָה נָשִׁים פִּרְיָם עֹלְלֵי טִפֻּחִים, אִם יֵהָרֵג בְּמִקְדַּשׁ אֲדֹנָי כֹּהֵן וְנָבִיא: שָׁכְבוּ לָאָרֶץ חוּצוֹת נַעַר וְזָקֵן, בְּתוּלֹתַי וּבַחוּרַי נָפְלוּ בֶחָרֶב, הָרַגְתָּ בְּיוֹם אַפֶּךָ, טָבַחְתָּ לֹא חָמָלְתָּ: תִּקְרָא כְיוֹם מוֹעֵד מְגוּרַי מִסָּבִיב וְלֹא הָיָה בְּיוֹם אַף יהוה פָּלִיט וְשָׂרִיד, אֲשֶׁר טִפַּחְתִּי וְרִבִּיתִי אֹיְבִי כִלָּם:","cond":["tishaaBeav"]},{"kind":"instruction","text":"פרק ג'","cond":["tishaaBeav"]},{"kind":"text","text":"אֲנִי הַגֶּבֶר רָאָה עֳנִי בְּשֵׁבֶט עֶבְרָתוֹ: אוֹתִי נָהַג וַיֹּלַךְ חֹשֶׁךְ וְלֹא אוֹר: אַךְ בִּי יָשֻׁב יַהֲפֹךְ יָדוֹ כָּל הַיּוֹם: בִּלָּה בְשָׂרִי וְעוֹרִי, שִׁבַּר עַצְמוֹתָי: בָּנָה עָלַי, וַיַּקַּף רֹאשׁ וּתְלָאָה: בְּמַחֲשַׁכִּים הוֹשִׁיבַנִי כְּמֵתֵי עוֹלָם: גָּדַר בַּעֲדִי וְלֹא אֵצֵא, הִכְבִּיד נְחָשְׁתִּי: גַּם כִּי אֶזְעַק וַאֲשַׁוֵּעַ שָׂתַם תְּפִלָּתִי: גָּדַר דְּרָכַי בְּגָזִית, נְתִיבֹתַי עִוָּה: דֹּב אֹרֵב הוּא לִי, אֲרִי בְּמִסְתָּרִים: דְּרָכַי סוֹרֵר וַיְפַשְּׁחֵנִי, שָׂמַנִי שֹׁמֵם: דָּרַךְ קַשְׁתּוֹ וַיַּצִּיבֵנִי כַּמַּטָּרָא לַחֵץ: הֵבִיא בְּכִלְיוֹתָי בְּנֵי אַשְׁפָּתוֹ: הָיִיתִי שְּׂחֹק לְכָל עַמִּי, נְגִינָתָם כָּל הַיּוֹם: הִשְׂבִּיעַנִי בַמְּרוֹרִים הִרְוַנִי לַעֲנָה: וַיַּגְרֵס בֶּחָצָץ שִׁנָּי, הִכְפִּישַׁנִי בָּאֵפֶר: וַתִּזְנַח מִשָּׁלוֹם נַפְשִׁי, נָשִׁיתִי טוֹבָה: וָאֹמַר אָבַד נִצְחִי וְתוֹחַלְתִּי מֵיהוה: זְכָר עָנְיִי וּמְרוּדִי, לַעֲנָה וָרֹאשׁ: זָכוֹר תִּזְכּוֹר וְתָשׁוֹחַ עָלַי נַפְשִׁי: זֹאת אָשִׁיב אֶל לִבִּי, עַל כֵּן אוֹחִיל: חַסְדֵי יהוה כִּי לֹא תָמְנוּ, כִּי לֹא כָלוּ רַחֲמָיו: חֲדָשִׁים לַבְּקָרִים רַבָּה אֱמוּנָתֶךָ: חֶלְקִי יהוה אָמְרָה נַפְשִׁי, עַל כֵּן אוֹחִיל לוֹ: טוֹב יהוה לְקֹוָו, לְנֶפֶשׁ תִּדְרְשֶׁנּוּ: טוֹב וְיָחִיל וְדוּמָם לִתְשׁוּעַת יהוה: טוֹב לַגֶּבֶר כִּי יִשָּׂא עֹל בִּנְעוּרָיו: יֵשֵׁב בָּדָד וְיִדֹּם כִּי נָטַל עָלָיו: יִתֵּן בֶּעָפָר פִּיהוּ, אוּלַי יֵשׁ תִּקְוָה: יִתֵּן לְמַכֵּהוּ לֶחִי, יִשְׂבַּע בְּחֶרְפָּה: כִּי לֹא יִזְנַח לְעוֹלָם אֲדֹנָי: כִּי אִם הוֹגָה וְרִחַם כְּרֹב חֲסָדָיו: כִּי לֹא עִנָּה מִלִּבּוֹ, וַיַּגֶּה בְּנֵי אִישׁ: לְדַכֵּא תַּחַת רַגְלָיו כֹּל אֲסִירֵי אָרֶץ: לְהַטּוֹת מִשְׁפַּט גָּבֶר נֶגֶד פְּנֵי עֶלְיוֹן: לְעַוֵּת אָדָם בְּרִיבוֹ אֲדֹנָי לֹא רָאָה: מִי זֶה אָמַר וַתֶּהִי, אֲדֹנָי לֹא צִוָּה: מִפִּי עֶלְיוֹן לֹא תֵצֵא הָרָעוֹת וְהַטּוֹב: מַה יִּתְאוֹנֵן אָדָם חָי, גֶּבֶר עַל חֲטָאָיו: נַחְפְּשָׂה דְרָכֵינוּ וְנַחְקֹרָה, וְנָשׁוּבָה עַד יהוה: נִשָּׂא לְבָבֵנוּ אֶל כַּפָּיִם, אֶל אֵל בַּשָּׁמָיִם: נַחְנוּ פָשַׁעְנוּ וּמָרִינוּ, אַתָּה לֹא סָלָחְתָּ: סַכֹּתָה בָאַף וַתִּרְדְּפֵנוּ, הָרַגְתָּ לֹא חָמָלְתָּ: סַכּוֹתָה בֶעָנָן לָךְ מֵעֲבוֹר תְּפִלָּה: סְחִי וּמָאוֹס תְּשִׂימֵנוּ בְּקֶרֶב הָעַמִּים: פָּצוּ עָלֵינוּ פִּיהֶם כָּל אֹיְבֵינוּ: פַּחַד וָפַחַת הָיָה לָנוּ, הַשֵּׁאת וְהַשָּׁבֶר: פַּלְגֵי מַיִם תֵּרַד עֵינִי עַל שֶׁבֶר בַּת עַמִּי: עֵינִי נִגְּרָה וְלֹא תִדְמֶה מֵאֵין הֲפֻגוֹת: עַד יַשְׁקִיף וְיֵרֶא יהוה מִשָּׁמָיִם: עֵינִי עוֹלְלָה לְנַפְשִׁי מִכֹּל בְּנוֹת עִירִי: צוֹד צָדוּנִי כַּצִּפּוֹר אֹיְבַי חִנָּם: צָמְתוּ בַבּוֹר חַיָּי וַיַּדּוּ אֶבֶן בִּי: צָפוּ מַיִם עַל רֹאשִׁי, אָמַרְתִּי נִגְזָרְתִּי: קָרָאתִי שִׁמְךָ יהוה מִבּוֹר תַּחְתִּיּוֹת: קוֹלִי שָׁמָעְתָּ, אַל תַּעְלֵם אָזְנְךָ לְרַוְחָתִי לְשַׁוְעָתִי: קָרַבְתָּ בְּיוֹם אֶקְרָאֶךָּ, אָמַרְתָּ אַל תִּירָא: רַבְתָּ אֲדֹנָי רִיבֵי נַפְשִׁי, גָּאַלְתָּ חַיָּי: רָאִיתָה יהוה עַוָּתָתִי, שָׁפְטָה מִשְׁפָּטִי: רָאִיתָה כָּל נִקְמָתָם, כָּל מַחְשְׁבֹתָם לִי: שָׁמַעְתָּ חֶרְפָּתָם יהוה, כָּל מַחְשְׁבֹתָם עָלָי: שִׂפְתֵי קָמַי וְהֶגְיוֹנָם עָלַי כָּל הַיּוֹם: שִׁבְתָּם וְקִימָתָם הַבִּיטָה, אֲנִי מַנְגִּינָתָם: תָּשִׁיב לָהֶם גְּמוּל, יהוה, כְּמַעֲשֵׂה יְדֵיהֶם: תִּתֵּן לָהֶם מְגִנַּת לֵב, תַּאֲלָתְךָ לָהֶם: תִּרְדֹּף בְּאַף וְתַשְׁמִידֵם מִתַּחַת שְׁמֵי יהוה:","cond":["tishaaBeav"]},{"kind":"instruction","text":"פרק ד'","cond":["tishaaBeav"]},{"kind":"text","text":"אֵיכָה יוּעַם זָהָב יִשְׁנֶא הַכֶּתֶם הַטּוֹב, תִּשְׁתַּפֵּכְנָה אַבְנֵי קֹדֶשׁ בְּרֹאשׁ כָּל חוּצוֹת: בְּנֵי צִיּוֹן הַיְקָרִים הַמְסֻלָּאִים בַּפָּז, אֵיכָה נֶחְשְׁבוּ לְנִבְלֵי חֶרֶשׂ מַעֲשֵׂה יְדֵי יוֹצֵר: גַּם תַּנִּים חָלְצוּ שַׁד, הֵינִיקוּ גּוּרֵיהֶן, בַּת עַמִּי לְאַכְזָר כַּיְעֵנִים בַּמִּדְבָּר: דָּבַק לְשׁוֹן יוֹנֵק אֶל חִכּוֹ בַּצָּמָא, עוֹלָלִים שָׁאֲלוּ לֶחֶם, פֹּרֵשׂ אֵין לָהֶם: הָאֹכְלִים לְמַעֲדַנִּים נָשַׁמּוּ בַּחוּצוֹת, הָאֱמֻנִים עֲלֵי תוֹלָע חִבְּקוּ אַשְׁפַּתּוֹת: וַיִּגְדַּל עֲוׂן בַּת עַמִּי מֵחַטַּאת סְדֹם הַהֲפוּכָה כְמוֹ רָגַע, וְלֹא חָלוּ בָהּ יָדָיִם: זַכּוּ נְזִירֶיהָ מִשֶּׁלֶג, צַחוּ מֵחָלָב, אָדְמוּ עֶצֶם מִפְּנִינִים, סַפִּיר גִּזְרָתָם: חָשַׁךְ מִשְּׁחוֹר תָּאֳרָם, לֹא נִכְּרוּ בַּחוּצוֹת, צָפַד עוֹרָם עַל עַצְמָם, יָבֵשׁ הָיָה כָעֵץ: טוֹבִים הָיוּ חַלְלֵי חֶרֶב מֵחַלְלֵי רָעָב, שֶׁהֵם יָזוּבוּ מְדֻקָּרִים מִתְּנוּבֹת שָׂדָי: יְדֵי נָשִׁים רַחֲמָנִיּוֹת בִּשְּׁלוּ יַלְדֵיהֶן, הָיוּ לְבָרוֹת לָמוֹ בְּשֶׁבֶר בַּת עַמִּי: כִּלָּה יהוה אֶת חֲמָתוֹ, שָׁפַךְ חֲרוֹן אַפּוֹ, וַיַּצֶּת אֵשׁ בְּצִיּוֹן וַתֹּאכַל יְסוֹדֹתֶיהָ: לֹא הֶאֱמִינוּ מַלְכֵי אֶרֶץ כֹּל יֹשְׁבֵי תֵבֵל, כִּי יָבֹא צַר וְאוֹיֵב בְּשַׁעֲרֵי יְרוּשָׁלָיִם: מֵחַטֹּאת נְבִיאֶיהָ, עֲוׂנוֹת כֹּהֲנֶיהָ, הַשֹּׁפְכִים בְּקִרְבָּהּ דַּם צַדִּיקִים: נָעוּ עִוְרִים בַּחוּצוֹת נְגֹאֲלוּ בַּדָּם, בְּלֹא יוּכְלוּ יִגְּעוּ בִּלְבֻשֵׁיהֶם: סוּרוּ טָמֵא, קָרְאוּ לָמוֹ, סוּרוּ סוּרוּ אַל תִּגָּעוּ, כִּי נָצוּ גַּם נָעוּ, אָמְרוּ בַּגּוֹיִם לֹא יוֹסִיפוּ לָגוּר: פְּנֵי יהוה חִלְּקָם לֹא יוֹסִיף לְהַבִּיטָם, פְּנֵי כֹהֲנִים לֹא נָשָׂאוּ וּזְקֵנִים לֹא חָנָנוּ: עוֹדֵינוּ תִּכְלֶינָה עֵינֵינוּ אֶל עֶזְרָתֵנוּ הָבֶל, בְּצִפִּיָּתֵנוּ צִפִּינוּ אֶל גּוֹי לֹא יוֹשִׁעַ: צָדוּ צְעָדֵינוּ מִלֶּכֶת בִּרְחֹבֹתֵינוּ, קָרַב קִצֵּינוּ מָלְאוּ יָמֵינוּ כִּי בָא קִצֵּינוּ: קַלִּים הָיוּ רֹדְפֵינוּ מִנִּשְׁרֵי שָׁמָיִם, עַל הֶהָרִים דְּלָקֻנוּ, בַּמִּדְבָּר אָרְבוּ לָנוּ: רוּחַ אַפֵּינוּ מְשִׁיחַ יהוה נִלְכַּד בִּשְׁחִיתוֹתָם, אֲשֶׁר אָמַרְנוּ בְּצִלּוֹ נִחְיֶה בַגּוֹיִם: שִׂישִׂי וְשִׂמְחִי בַּת אֱדוֹם יוֹשֶׁבֶת בְּאֶרֶץ עוּץ, גַּם עָלַיִךְ תַּעֲבָר כּוֹס, תִּשְׁכְּרִי וְתִתְעָרִי: תַּם עֲוׂנֵךְ בַּת צִיּוֹן, לֹא יוֹסִיף לְהַגְלוֹתֵךְ, פָּקַד עֲוׂנֵךְ בַּת אֱדוֹם, גִּלָּה עַל חַטֹּאתָיִךְ:","cond":["tishaaBeav"]},{"kind":"instruction","text":"פרק ה'","cond":["tishaaBeav"]},{"kind":"text","text":"זְכֹר יהוה מֶה הָיָה לָנוּ, הַבִּיטָה וּרְאֵה אֶת חֶרְפָּתֵנוּ: נַחֲלָתֵנוּ נֶהֶפְכָה לְזָרִים, בָּתֵּינוּ לְנָכְרִים: יְתוֹמִים הָיִינוּ וְאֵין אָב, אִמֹּתֵינוּ כְּאַלְמָנוֹת: מֵימֵינוּ בְּכֶסֶף שָׁתִינוּ, עֵצֵינוּ בִּמְחִיר יָבֹאוּ: עַל צַוָּארֵנוּ נִרְדָּפְנוּ, יָגַעְנוּ וְלֹא הוּנַח לָנוּ: מִצְרַיִם נָתַנּוּ יָד, אַשּׁוּר לִשְׂבֹּעַ לָחֶם: אֲבֹתֵינוּ חָטְאוּ וְאֵינָם, וַאֲנַחְנוּ עֲוׂנֹתֵיהֶם סָבָלְנוּ: עֲבָדִים מָשְׁלוּ בָנוּ, פֹּרֵק אֵין מִיָּדָם: בְּנַפְשֵׁנוּ נָבִיא לַחְמֵנוּ מִפְּנֵי חֶרֶב הַמִּדְבָּר: עוֹרֵנוּ כְּתַנּוּר נִכְמָרוּ מִפְּנֵי זַלְעֲפוֹת רָעָב: נָשִׁים בְּצִיּוֹן עִנּוּ, בְּתֻלֹת בְּעָרֵי יְהוּדָה: שָׂרִים בְּיָדָם נִתְלוּ, פְּנֵי זְקֵנִים לֹא נֶהְדָּרוּ: בַּחוּרִים טְחוֹן נָשָׂאוּ, וּנְעָרִים בָּעֵץ כָּשָׁלוּ: זְקֵנִים מִשַּׁעַר שָׁבָתוּ, בַּחוּרִים מִנְּגִינָתָם: שָׁבַת מְשׂוֹשׂ לִבֵּנוּ, נֶהְפַּךְ לְאֵבֶל מְחֹלֵנוּ: נָפְלָה עֲטֶרֶת רֹאשֵׁנוּ, אוֹי נָא לָנוּ כִּי חָטָאנוּ: עַל זֶה הָיָה דָוֶה לִבֵּנוּ, עַל אֵלֶּה חָשְׁכוּ עֵינֵינוּ: עַל הַר צִיּוֹן שֶׁשָּׁמֵם, שׁוּעָלִים הִלְּכוּ בוֹ: אַתָּה יהוה לְעוֹלָם תֵּשֵׁב, כִּסְאֲךָ לְדֹר וָדוֹר: לָמָּה לָנֶצַח תִּשְׁכָּחֵנוּ, תַּעַזְבֵנוּ לְאֹרֶךְ יָמִים: הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם: כִּי אִם מָאֹס מְאַסְתָּנוּ, קָצַפְתָּ עָלֵינוּ עַד מְאֹד:","cond":["tishaaBeav"]},{"kind":"special","text":"הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם:","cond":["tishaaBeav"]},{"kind":"header","text":"קינות לליל תשעה באב","cond":["tishaaBeav"]},{"kind":"instruction","text":"קינות לליל תשעה באב\n\nקינה א'","cond":["tishaaBeav"]},{"kind":"text","text":"זְכֹר יהוה מֶה-הָיָה לָנוּ אוֹי. הַבִּיטָה וּרְאֵה אֶת-חֶרְפָּתֵנוּ: אוֹי מֶה הָיָה לָנוּ.\nנַחֲלָתֵנוּ נֶהֶפְכָה לְזָרִים אוֹי. בָּתֵּינוּ לְנָכְרִים: אוֹי מֶה הָיָה לָנוּ.\nיְתוֹמִים הָיִינוּ וְאֵין אָב אוֹי. אִמּוֹתֵינוּ מְקוֹנְנוֹת בְּחֹדֶשׁ אָב. אוֹי מֶה הָיָה לָנוּ.\nמֵימֵינוּ בְּכֶסֶף שָׁתִינוּ אוֹי. כִּי נִסּוּךְ הַמַּיִם בָּזִינוּ. אוֹי מֶה הָיָה לָנוּ.\nעַל צַוָּארֵנוּ נִרְדָּפְנוּ אוֹי. כִּי שִׂנְאַת חִנָּם רָדָפְנוּ. אוֹי מֶה הָיָה לָנוּ.\nמִצְרַיִם נָתַנּוּ יָד אוֹי. וְאַשּׁוּר צָדוּנוּ כְּצַיָּד. אוֹי מֶה הָיָה לָנוּ.\nאֲבֹתֵינוּ חָטְאוּ וְאֵינָם אוֹי. וַאֲנַחְנוּ סוֹבְלִים אֶת עֲוׂנָם. אוֹי מֶה הָיָה לָנוּ.\nעֲבָדִים מָשְׁלוּ בָנוּ אוֹי. כִּי שִׁלּוּחַ עֲבָדִים בִּטַּלְנוּ. אוֹי מֶה הָיָה לָנוּ.\nבְּנַפְשֵׁנוּ נָבִיא לַחְמֵנוּ אוֹי. כִּי קָפַצְנוּ מֵעָנִי יָדֵנוּ. אוֹי מֶה הָיָה לָנוּ.\nעוֹרֵנוּ כְּתַנּוּר נִכְמָרוּ אוֹי. כִּי כְבוֹדָם בְּקָלוֹן הֵמִירוּ. אוֹי מֶה הָיָה לָנוּ.\nנָשִׁים בְּצִיּוֹן עִנּוּ אוֹי. כִּי אִישׁ אֶת אֵשֶׁת רֵעֵהוּ טִמְּאוּ וְזִנּוּ. אוֹי מֶה הָיָה לָנוּ.\nשָׂרִים בְּיָדָם נִתְלוּ אוֹי. כִּי גְּזֵלַת הֶעָנִי חָמְסוּ וְגָזְלוּ. אוֹי מֶה הָיָה לָנוּ.\nבַּחוּרִים טְחוֹן נָשָׂאוּ אוֹי. כִּי בְּבֵית זוֹנָה נִמְצָאוּ. אוֹי מֶה הָיָה לָנוּ.\nזְקֵנִים מִשַּׁעַר שָׁבָתוּ אוֹי. כִּי מִשְׁפַּט יָתוֹם וְאַלְמָנָה עִוְּתוּ. אוֹי מֶה הָיָה לָנוּ.\nשָׁבַת מְשׂוֹשׂ לִבֵּנוּ אוֹי. כִּי נִבְטְלוּ עוֹלֵי רְגָלֵינוּ. אוֹי מֶה הָיָה לָנוּ.\nנָפְלָה עֲטֶרֶת רֹאשֵׁנוּ אוֹי. כִּי נִשְׂרַף בֵּית מִקְדָּשֵׁנוּ. אוֹי מֶה הָיָה לָנוּ.\nעַל זֶה הָיָה דָוֶה לִבֵּנוּ אוֹי. כִּי נֻטַּל כְּבוֹד בֵּית מַאֲוָיֵנוּ. אוֹי מֶה הָיָה לָנוּ.\nעַל הַר צִיּוֹן שֶׁשָּׁמֵם אוֹי. כִּי נִתַּן עָלָיו שִׁקּוּץ מְשׁוֹמֵם. אוֹי מֶה הָיָה לָנוּ.\nאַתָּה יהוה לְעוֹלָם תֵּשֵׁב, כִּסְאֲךָ לְדוֹר וָדוֹר: לָמָּה לָנֶצַח תִּשְׁכָּחֵנוּ, תַּעַזְבֵנוּ לְאֹרֶךְ יָמִים: הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם: כִּי אִם מָאֹס מְאַסְתָּנוּ, קָצַפְתָּ עָלֵינוּ עַד מְאֹד:\nהֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה חַדֵּשׁ יָמֵינוּ כְּקֶדֶם:","cond":["tishaaBeav"]},{"kind":"instruction","text":"קינה ב'\nקינה לליל תשעה באב שחל במוצאי שבת:","cond":["tishaaBeav","sun"]},{"kind":"text","text":"אֵיךְ מִפִּי בֵּן וּבַת, הֲגוֹת קִינִים רַבַּת, תְּמוּר שִׁירִים וְחֶדְוַת.\nוִיהִי נֹעַם נִשְׁבַּת בְּמוֹצָאֵי שַׁבָּת.\n\nאוֹי כִּי נִגְזְרָה גְּזֵרָה, בָּחֳרִי אַף וְגַם עֶבְרָה, וְאַפּוֹ בָּנוּ חָרָה, וּבָעֲרָה חֲמָתוֹ כְּלַבַּת.\nוִיהִי נֹעַם נִשְׁבַּת בְּמוֹצָאֵי שַׁבָּת.\n\nאוֹי כִּי בָתֵּינוּ שִׁנּוּ, וּבְתוּלוֹתֵינוּ עִנּוּ, וּפָנֵינוּ נִשְׁתַּנּוּ, וְגַם הֻשְׁחֲרוּ כְּמַחֲבַת.\nוִיהִי נֹעַם נִשְׁבַּת בְּמוֹצָאֵי שַׁבָּת.\n\nאוֹי כִּי שַׁדּוּנוּ, וְגַם הִפִּילוּ בָנוּ פְּגָרִים, בְּנֵי צִיּוֹן הַיְקָרִים, הָיוּ נְצוּרִים כְּבָבַת.\nוִיהִי נֹעַם נִשְׁבַּת בְּמוֹצָאֵי שַׁבָּת.\n\nאוֹי כִּי נָפְלָה עֲטֶרֶת, וְגָבְרָה כָּתֵף סוֹרֶרֶת, וְחָדַל הוֹד תִּפְאֶרֶת, צִמְצוּם שֶׁכֶן חִבַּת.\nוִיהִי נֹעַם נִשְׁבַּת בְּמוֹצָאֵי שַׁבָּת.\n\nאוֹי כִּי נֻטְּלָה מְנוֹרָה, וּקְטֹרֶת לְבֹנָה הַטְּהוֹרָה, וְנִבְזָה גָּזִית מְיֻקָּרָה, אָכְלָה אֶרֶץ זָבַת.\nוִיהִי נֹעַם נִשְׁבַּת בְּמוֹצָאֵי שַׁבָּת.","cond":["tishaaBeav","sun"]},{"kind":"instruction","text":"קינה ג'","cond":["tishaaBeav"]},{"kind":"text","text":"בְּלֵיל זֶה יִבְכָּיוּן וְיֵילִילוּ בָּנַי, בְּלֵיל זֶה חָרַב בֵּית קָדְשִׁי וְנִשְׂרְפוּ אַרְמוֹנַי. וְכָל בֵּית יִשְׂרָאֵל יֶהְגּוּ בִיגוֹנַי. וְיִבְכּוּ אֶת הַשְּׂרֵפָה אֲשֶׁר שָׂרַף יהוה:\n\nבְּלֵיל זֶה תְּיַלֵּל מַר עֲנִיָּה נֶחְדֶּלֶת, וּמִבֵּית אָבִיהָ בַּחַיִּים מֻבְדֶּלֶת. וְיָצְאָה מִבֵּיתוֹ וְנִסְגַּר הַדֶּלֶת, וְהָלְכָה בַּשִּׁבְיָה בְּכָל פֶּה נֶאֱכֶלֶת. בְּיוֹם שֻׁלְּחָה בְּאֵשׁ בּוֹעֶרֶת וְאוֹכֶלֶת, וְאֵשׁ עִם גַּחֶלֶת יָצְאָה מֵאֵת יהוה.\nבְּלֵיל זֶה יִבְכָּיוּן וְיֵילִילוּ בָּנַי, בְּלֵיל זֶה חָרַב בֵּית קָדְשִׁי וְנִשְׂרְפוּ אַרְמוֹנַי.\n\nבְּלֵיל זֶה הַגַּלְגַּל סִבֵּב הַחוֹבָה, רִאשׁוֹן גַּם שֵׁנִי בֵּיתִי נֶחְרְבָה. וְעוֹד לֹא רֻחָמָה בַּת הַשּׁוֹבָבָה, הֻשְׁקְתָה מֵי רוֹשׁ וְאֶת בִּטְנָהּ צָבָה. וְשֻׁלְּחָה מִבֵּיתוֹ וְגַם נָשְׁתָה טוֹבָה, גְּדוֹלָה הַשִּׂנְאָה מֵאֵת אֲשֶׁר אֲהֵבָהּ, וּכְאַלְמְנוּת חַיּוּת כְּאִשָּׁה נֶעֱזָבָה. וַתֹּאמֶר צִיּוֹן עֲזָבַנִי יהוה.\nבְּלֵיל זֶה יִבְכָּיוּן וְיֵילִילוּ בָּנַי, בְּלֵיל זֶה חָרַב בֵּית קָדְשִׁי וְנִשְׂרְפוּ אַרְמוֹנַי.\n\nבְּלֵיל זֶה קָדַרְתִּי וְחָשְׁכוּ הַמְּאוֹרוֹת, לְחֻרְבַּן בֵּית קָדְשִׁי וּבִטּוּל מִשְׁמָרוֹת. בְּלֵיל זֶה סַבּוּנִי אֲפָפוּנִי צָרוֹת, וְגַם קָרָא מוֹעֵד בְּדִין חָמֵשׁ גְּזֵרוֹת. בְּכִי חִנָּם בָּכוּ וְנִקְבַּע לְדוֹרוֹת, יַעַן כִּי הָיְתָה סִבָּה מֵאֵת יהוה.\nבְּלֵיל זֶה יִבְכָּיוּן וְיֵילִילוּ בָּנַי, בְּלֵיל זֶה חָרַב בֵּית קָדְשִׁי וְנִשְׂרְפוּ אַרְמוֹנַי.\n\nבְּלֵיל זֶה אֵרְעוּ בוֹ חָמֵשׁ מְאוֹרָעוֹת, גָּזַר עַל אָבוֹת בִּפְרֹעַ פְּרָעוֹת. וְדָבְקוּ בוֹ צָרוֹת מְצֵרוֹת וְגַם רָעוֹת, יוֹם מוּכָן הָיָה בִּפְגֹּעַ פְּגָעוֹת. וְהֶעֱמִיד הָאוֹיֵב וְהֵרִים קוֹל זְוָעוֹת, קוּם כִּי זֶה הַיּוֹם אֲשֶׁר אָמַר יהוה.\nבְּלֵיל זֶה יִבְכָּיוּן וְיֵילִילוּ בָּנַי, בְּלֵיל זֶה חָרַב בֵּית קָדְשִׁי וְנִשְׂרְפוּ אַרְמוֹנַי.","cond":["tishaaBeav"]},{"kind":"instruction","text":"קינה ד'","cond":["tishaaBeav"]},{"kind":"text","text":"שֹׁמְרוֹן קוֹל תִּתֵּן: מְצָאוּנִי עֲוׂנַי, לְאֶרֶץ אַחֶרֶת יְצָאוּנִי בָנַי.\nוְאָהֳלִיבָה תִּזְעַק: נִשְׂרְפוּ אַרְמוֹנַי.\nוַתֹּאמֶר צִיּוֹן: עֲזָבַנִי יהוה.\n\nלֹא לָךְ, אָהֳלִיבָה, חֲשֹׁב עָנְיֵךְ כְּעָנְיִי, הֲתַמְשִׁילִי חָלְיֵךְ לְשִׁבְרִי וּלְחָלְיִי? אֲנִי אָהֳלָה סוּרָה בָּגַדְתִּי בְקָשְׁיִי, וְקָם עָלַי כַּחֲשִׁי וְעָנָה בִי מֶרְיִי, וּלְמִקְצָת הַיָּמִים שִׁלַּמְתִּי נִשְׁיִי, וְתִגְלַת פִּלְאֶסֶר אָכַל אֶת פִּרְיִי, חֶמְדָּתִי פָּשַׁט וְהִצִּיל אֶת עֶדְיִי, וְלַחֲלַח וְחָבוֹר נָשָׂא אֶת שִׁבְיִי. דֹּמִי, אָהֳלִיבָה, וְאַל תִּבְכִּי כְּבִכְיִי, שְׁנָתַיִךְ אָרְכוּ, וְלֹא אָרְכוּ שָׁנַי.\n\nוְאָהֳלִיבָה תִּזְעַק: נִשְׂרְפוּ אַרְמוֹנַי.\nוַתֹּאמֶר צִיּוֹן: עֲזָבַנִי יהוה.\n\nמְשִׁיבָה אָהֳלִיבָה: אֲנִי כֵן נֶעֱקַשְׁתִּי, וּבְאַלּוּף נְעוּרַי כְּאָהֳלָה בָּגַדְתִּי. דֹּמִי, אַהֳלָה, כִּי יְגוֹנִי זָכַרְתִּי. נָדַדְתְּ אַתְּ אַחַת, וְרַבּוֹת נָדַדְתִּי. הִנֵּה, בְּיַד הַכַּשְׂדִּים פַּעֲמַיִם נִלְכַּדְתִּי, וּשְׁבִיָּה עֲנִיָּה לְבָבֶל יָרַדְתִּי, וְנִשְׂרַף הַהֵיכָל אֲשֶׁר בּוֹ נִכְבַּדְתִּי, וּלְשִׁבְעִים שָׁנָה בְּבָבֶל נִפְקַדְתִּי, וְשַׁבְתִּי לְצִיּוֹן עוֹד וְהֵיכָל יָסַדְתִּי, גַּם זֹאת הַפַּעַם מְעַט לֹא עָמַדְתִּי, עַד לְקָחַנִי אֱדוֹם וְכִמְעַט אָבַדְתִּי, וְעַל כָּל הָאֲרָצוֹת נָפְצוּ הֲמוֹנַי.\n\nוְאָהֳלִיבָה תִּזְעַק: נִשְׂרְפוּ אַרְמוֹנַי.\nוַתֹּאמֶר צִיּוֹן: עֲזָבַנִי יהוה.\n\nהַחוֹמֵל עַל דַּל, חֲמֹל עַל דַּלּוּתָם, וּרְאֵה שׁוֹמְמוּתָם וְאֹרֶךְ גָּלוּתָם. אַל תִּקְצֹף עַד מְאֹד, וּרְאֵה שִׁפְלוּתָם, וְאַל לָעַד תִּזְכֹּר עֲוֹנָם וְסִכְלוּתָם. רְפָא נָא אֶת שִׁבְרָם, וְנַחֵם אֲבֵלוּתָם, כִּי אַתָּה שִׂבְרָם וְאַתָּה אֱיָלוּתָם.\nחַדֵּשׁ יָמֵינוּ כִּימֵי קַדְמוֹנַי, כְּנָאֳמֶךָ: \"בּוֹנֵה יְרוּשָׁלַיִם יהוה\".","cond":["tishaaBeav"]},{"kind":"instruction","text":"קינה ה'","cond":["tishaaBeav"]},{"kind":"text","text":"עַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nאָז בַּחֲטָאֵינוּ חָרַב מִקְדָּשׁ וּבַעֲוׂנוֹתֵינוּ נִשְׂרַף הֵיכָל. בְּאֶרֶץ חֻבְּרָה לָהּ קָשְׁרָה מִסְפֵּד, וּצְבָא הַשָּׁמַיִם נָשְׂאוּ קִינָה.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nגַּם בָּכוּ בְּמֶרֶר שִׁבְטֵי יַעֲקֹב, וְאַף מַזָּלוֹת יִזְּלוּ דִּמְעָה. דִּגְלֵי יְשֻׁרוּן חָפוּ רֹאשָׁם, וְכִימָה וּכְסִיל קָדְרוּ פְּנֵיהֶם.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nהֶעְתִּירוּ אָבוֹת וְלֹא שָׁמַע אֵל, צָעֲקוּ בָנִים וְלֹא עָנָה אָב. וְקוֹל הַתֹּר נִשְׁמַע בַּמָּרוֹם, וְרוֹעֶה נֶאֱמָן לֹא הִטָּה אֹזֶן.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nזֶרַע קֹדֶשׁ לָבְשׁוּ שַׂקִּים, וּצְבָא הַשָּׁמַיִם גַּם הֵם שַׂק הוּשַׂם כְּסוּתָם. חָשַׁךְ הַשֶּׁמֶשׁ וְיָרֵחַ קָדַר, וְכוֹכָבִים וּמַזָּלוֹת אָסְפוּ נָגְהָם.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nטָלֶה רִאשׁוֹן בָּכָה בְּמַר נֶפֶשׁ, עַל כִּי כְבָשָׂיו לָטֶבַח הוּבָלוּ. יְלָלָה הִשְׁמִיעַ שׁוֹר בַּמְּרוֹמִים, כִּי עַל צַוָּארֵנוּ נִרְדַּפְנוּ כֻּלָּנוּ.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nכּוֹכַב תְּאוֹמִים נִרְאָה חָלוּק, כִּי דַּם אַחִים נִשְׁפַּךְ כַּמַּיִם. לָאָרֶץ בִּקֵּשׁ לִפֹּל סַרְטָן, כִּי נִתְעַלַּפְנוּ מִפְּנֵי צָמָא.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nמָרוֹם נִבְעַת מִפְּנֵי אַרְיֵה, כִּי שַׁאֲגָתֵנוּ לֹא עָלְתָה לַמָּרוֹם. נֶהֶרְגוּ בְתוּלוֹת וְגַם בַּחוּרִים, כִּי עַל כֵּן בְּתוּלָה קָדְרָה פָנֶיהָ.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nסִבֵּב מֹאזְנַיִם וּבִקֵּשׁ תְּחִנָּה, כִּי נִבְחַר לָנוּ מָוֶת מֵחַיִּים. עַקְרָב לָבַשׁ פַּחַד וּרְעָדָה, כִּי בְּחֶרֶב וּבְרָעָב שְׁפָטָנוּ צוּרֵנוּ.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nפַּלְגֵי מַיִם הוֹרִידוּ דִּמְעָה כַּנַּחַל, כִּי אוֹת בַּקֶּשֶׁת לֹא נִתַּן לָנוּ. צָפוּ מַיִם עַל רֹאשֵׁנוּ, וּבִדְלִי מָלֵא חִכֵּנוּ יָבֵשׁ.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nקֵרַבְנוּ קָרְבָּן וְלֹא נִתְקַבֵּל, וּגְדִי פָּסַק שְׂעִיר חַטֹּאתֵינוּ. רַחֲמָנִיּוֹת בִּשְּׁלוּ יַלְדֵּיהֶן, וּמַזַּל דָּגִים הֶעֱלִים עֵינָיו.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nשָׁכַחְנוּ שַׁבָּת בְּלִבּוֹת שׁוֹבָבִים, שַׁדַּי שִׁכַּח כָּל צִדְקוֹתֵינוּ. תְּקַנֵּא לְצִיּוֹן קִנְאָה גְּדוֹלָה, וְתָאִיר לְרַבָּתִי עָם מֵאוֹר נָגְהֶךָ.\n\nתְּרַחֵם צִיּוֹן כַּאֲשֶׁר אָמַרְתָּ, וּתְכוֹנְנֶהָ כַּאֲשֶׁר דִּבַּרְתָּ. תְּמַהֵר יְשׁוּעָה וְתָחִישׁ גְּאֻלָּה וְתָשׁוּב לִירוּשָׁלַיִם בְּרַחֲמִים רַבִּים, כַּכָּתוּב עַל יַד נְבִיאֶךָ: לָכֵן כֹּה אָמַר יהוה: שַׁבְתִּי לִירוּשָׁלַיִם בְּרַחֲמִים, בֵּיתִי יִבָּנֶה בָּהּ נְאֻם יהוה צְבָאוֹת, וְקָו יִנָּטֶה עַל יְרוּשָׁלָיִם: וְנֶאֱמַר עוֹד קְרָא לֵאמֹר: כֹּה אָמַר יהוה צְבָאוֹת: עוֹד תְּפוּצֶנָה עָרַי מִטּוֹב, וְנִחַם יהוה עוֹד אֶת צִיּוֹן וּבָחַר עוֹד בִּירוּשָׁלָיִם: וְנֶאֱמַר: כִּי נִחַם יהוה צִיּוֹן, נִחַם כָּל חָרְבֹתֶיהָ, וַיָּשֶׂם מִדְבָּרָהּ כְּעֵדֶן וְעַרְבָתָהּ כְּגַן יהוה, שָׂשׂוֹן וְשִׂמְחָה יִמָּצֵא בָהּ תּוֹדָה וְקוֹל זִמְרָה:","cond":["tishaaBeav"]},{"kind":"header","text":"מגילת אסתר","cond":["megilatEster"]},{"kind":"instruction","text":"הקורא את המגילה מברך לפניה שלוש ברכות גם בלילה וגם ביום. לדעת השו\"ע מברכים שהחיינו רק בלילה (ואם לא קרא בלילה יברך ביום). בברכת שהחיינו ביום יכוון גם על שאר מצוות היום: מתנות לאביונים, משלוח מנות ומשתה ושמחה. הנוהגים כדעת השו\"ע יכוונו על זה בלילה.","cond":["megilatEster"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ עַל מִקְרָא מְגִלָּה.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁעָשָׂה נִסִּים לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁהֶחֱיָנוּ וְקִיְּמָנוּ וְהִגִּיעָנוּ לַזְּמַן הַזֶּה.","cond":["megilatEster"]},{"kind":"header","text":"פרק א'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק א'","cond":["megilatEster"]},{"kind":"text","text":"וַיְהִי בִּימֵי אֲחַשְׁוֵרוֹשׁ, הוּא אֲחַשְׁוֵרוֹשׁ הַמֹּלֵךְ מֵהֹדּוּ וְעַד כּוּשׁ, שֶׁבַע וְעֶשְׂרִים וּמֵאָה מְדִינָה: בַּיָּמִים הָהֵם, כְּשֶׁבֶת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ עַל כִּסֵּא מַלְכוּתוֹ אֲשֶׁר בְּשׁוּשַׁן הַבִּירָה: בִּשְׁנַת שָׁלוֹשׁ לְמָלְכוֹ עָשָׂה מִשְׁתֶּה לְכָל שָׂרָיו וַעֲבָדָיו, חֵיל פָּרַס וּמָדַי הַפַּרְתְּמִים וְשָׂרֵי הַמְּדִינוֹת לְפָנָיו: בְּהַרְאֹתוֹ אֶת עֹשֶׁר כְּבוֹד מַלְכוּתוֹ וְאֶת יְקָר תִּפְאֶרֶת גְּדוּלָּתוֹ, יָמִים רַבִּים שְׁמוֹנִים וּמְאַת יוֹם: וּבִמְלוֹאת הַיָּמִים הָאֵלֶּה עָשָׂה הַמֶּלֶךְ לְכָל הָעָם הַנִּמְצְאִים בְּשׁוּשַׁן הַבִּירָה לְמִגָּדוֹל וְעַד קָטָן מִשְׁתֶּה שִׁבְעַת יָמִים, בַּחֲצַר גִּנַּת בִּיתַן הַמֶּלֶךְ: חוּר כַּרְפַּס וּתְכֵלֶת אָחוּז בְּחַבְלֵי בוּץ וְאַרְגָּמָן עַל גְּלִילֵי כֶסֶף וְעַמּוּדֵי שֵׁשׁ, מִטּוֹת זָהָב וָכֶסֶף עַל רִצְפַת בַּהַט וָשֵׁשׁ וְדַר וְסֹחָרֶת: וְהַשְׁקוֹת בִּכְלֵי זָהָב וְכֵלִים מִכֵּלִים שׁוֹנִים, וְיֵין מַלְכוּת רָב כְּיַד הַמֶּלֶךְ: וְהַשְּׁתִיָּה כַדָּת אֵין אֹנֵס, כִּי כֵן יִסַּד הַמֶּלֶךְ עַל כָּל רַב בֵּיתוֹ לַעֲשׂוֹת כִּרְצוֹן אִישׁ וָאִישׁ: גַּם וַשְׁתִּי הַמַּלְכָּה עָשְׂתָה מִשְׁתֵּה נָשִׁים, בֵּית הַמַּלְכוּת אֲשֶׁר לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: בַּיּוֹם הַשְּׁבִיעִי כְּטוֹב לֵב הַמֶּלֶךְ בַּיָּיִן, אָמַר לִמְהוּמָן בִּזְּתָא חַרְבוֹנָא בִּגְתָא וַאֲבַגְתָא זֵתַר וְכַרְכַּס שִׁבְעַת הַסָּרִיסִים הַמְשָׁרְתִים אֶת פְּנֵי הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: לְהָבִיא אֶת וַשְׁתִּי הַמַּלְכָּה לִפְנֵי הַמֶּלֶךְ בְּכֶתֶר מַלְכוּת, לְהַרְאוֹת הָעַמִּים וְהַשָּׂרִים אֶת יָפְיָהּ, כִּי טוֹבַת מַרְאֶה הִיא: וַתְּמָאֵן הַמַּלְכָּה וַשְׁתִּי לָבוֹא בִּדְבַר הַמֶּלֶךְ אֲשֶׁר בְּיַד הַסָּרִיסִים, וַיִּקְצֹף הַמֶּלֶךְ מְאֹד וַחֲמָתוֹ בָּעֲרָה בוֹ: וַיֹּאמֶר הַמֶּלֶךְ לַחֲכָמִים יֹדְעֵי הָעִתִּים, כִּי כֵן דְּבַר הַמֶּלֶךְ לִפְנֵי כָּל יֹדְעֵי דָּת וָדִין: וְהַקָּרֹב אֵלָיו כַּרְשְׁנָא שֵׁתָר אַדְמָתָא תַרְשִׁישׁ מֶרֶס מַרְסְנָא מְמוּכָן, שִׁבְעַת שָׂרֵי פָּרַס וּמָדַי רֹאֵי פְּנֵי הַמֶּלֶךְ הַיֹּשְׁבִים רִאשֹׁנָה בַּמַּלְכוּת: כְּדָת מַה לַּעֲשׂוֹת בַּמַּלְכָּה וַשְׁתִּי, עַל אֲשֶׁר לֹא עָשְׂתָה אֶת מַאֲמַר הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ בְּיַד הַסָּרִיסִים: וַיֹּאמֶר מְמוּכָן לִפְנֵי הַמֶּלֶךְ וְהַשָּׂרִים, לֹא עַל הַמֶּלֶךְ לְבַדּוֹ עָוְתָה וַשְׁתִּי הַמַּלְכָּה, כִּי עַל כָּל הַשָּׂרִים וְעַל כָּל הָעַמִּים אֲשֶׁר בְּכָל מְדִינוֹת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: כִּי יֵצֵא דְבַר הַמַּלְכָּה עַל כָּל הַנָּשִׁים לְהַבְזוֹת בַּעְלֵיהֶן בְּעֵינֵיהֶן, בְּאָמְרָם הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ אָמַר לְהָבִיא אֶת וַשְׁתִּי הַמַּלְכָּה לְפָנָיו וְלֹא בָאָה: וְהַיּוֹם הַזֶּה תֹּאמַרְנָה שָׂרוֹת פָּרַס וּמָדַי אֲשֶׁר שָׁמְעוּ אֶת דְּבַר הַמַּלְכָּה לְכֹל שָׂרֵי הַמֶּלֶךְ, וּכְדַי בִּזָּיוֹן וָקָצֶף: אִם עַל הַמֶּלֶךְ טוֹב יֵצֵא דְבַר מַלְכוּת מִלְּפָנָיו וְיִכָּתֵב בְּדָתֵי פָרַס וּמָדַי וְלֹא יַעֲבוֹר, אֲשֶׁר לֹא תָבוֹא וַשְׁתִּי לִפְנֵי הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ וּמַלְכוּתָהּ יִתֵּן הַמֶּלֶךְ לִרְעוּתָהּ הַטּוֹבָה מִמֶּנָּה: וְנִשְׁמַע פִּתְגָם הַמֶּלֶךְ אֲשֶׁר יַעֲשֶׂה בְּכָל מַלְכוּתוֹ כִּי רַבָּה הִיא, וְכָל הַנָּשִׁים יִתְּנוּ יְקָר לְבַעְלֵיהֶן לְמִגָּדוֹל וְעַד קָטָן: וַיִּיטַב הַדָּבָר בְּעֵינֵי הַמֶּלֶךְ וְהַשָּׂרִים, וַיַּעַשׂ הַמֶּלֶךְ כִּדְבַר מְמוּכָן: וַיִּשְׁלַח סְפָרִים אֶל כָּל מְדִינוֹת הַמֶּלֶךְ, אֶל מְדִינָה וּמְדִינָה כִּכְתָבָהּ וְאֶל עַם וָעָם כִּלְשׁוֹנוֹ, לִהְיוֹת כָּל אִישׁ שֹׂרֵר בְּבֵיתוֹ וּמְדַבֵּר כִּלְשׁוֹן עַמּוֹ:","cond":["megilatEster"]},{"kind":"header","text":"פרק ב'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ב'","cond":["megilatEster"]},{"kind":"text","text":"אַחַר הַדְּבָרִים הָאֵלֶּה כְּשֹׁךְ חֲמַת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, זָכַר אֶת וַשְׁתִּי וְאֵת אֲשֶׁר עָשָׂתָה וְאֵת אֲשֶׁר נִגְזַר עָלֶיהָ: וַיֹּאמְרוּ נַעֲרֵי הַמֶּלֶךְ מְשָׁרְתָיו, יְבַקְשׁוּ לַמֶּלֶךְ נְעָרוֹת בְּתוּלוֹת טוֹבוֹת מַרְאֶה: וְיַפְקֵד הַמֶּלֶךְ פְּקִידִים בְּכָל מְדִינוֹת מַלְכוּתוֹ, וְיִקְבְּצוּ אֶת כָּל נַעֲרָה בְתוּלָה טוֹבַת מַרְאֶה אֶל שׁוּשַׁן הַבִּירָה אֶל בֵּית הַנָּשִׁים אֶל יַד הֵגֶא סְרִיס הַמֶּלֶךְ שֹׁמֵר הַנָּשִׁים, וְנָתוֹן תַּמְרוּקֵיהֶן: וְהַנַּעֲרָה אֲשֶׁר תִּיטַב בְּעֵינֵי הַמֶּלֶךְ תִּמְלֹךְ תַּחַת וַשְׁתִּי, וַיִּיטַב הַדָּבָר בְּעֵינֵי הַמֶּלֶךְ וַיַּעַשׂ כֵּן:","cond":["megilatEster"]},{"kind":"special","text":"אִישׁ יְהוּדִי הָיָה בְּשׁוּשַׁן הַבִּירָה, וּשְׁמוֹ מָרְדֳּכַי בֶּן יָאִיר בֶּן שִׁמְעִי בֶּן קִישׁ אִישׁ יְמִינִי:","cond":["megilatEster"]},{"kind":"text","text":"אֲשֶׁר הָגְלָה מִירוּשָׁלַיִם עִם הַגֹּלָה אֲשֶׁר הָגְלְתָה עִם יְכָנְיָה מֶלֶךְ יְהוּדָה, אֲשֶׁר הֶגְלָה נְבוּכַדְנֶאצַּר מֶלֶךְ בָּבֶל: וַיְהִי אֹמֵן אֶת הֲדַסָּה הִיא אֶסְתֵּר בַּת דֹּדוֹ כִּי אֵין לָהּ אָב וָאֵם, וְהַנַּעֲרָה יְפַת תֹּאַר וְטוֹבַת מַרְאֶה וּבְמוֹת אָבִיהָ וְאִמָּהּ לְקָחָהּ מָרְדֳּכַי לוֹ לְבַת: וַיְהִי בְּהִשָּׁמַע דְּבַר הַמֶּלֶךְ וְדָתוֹ, וּבְהִקָּבֵץ נְעָרוֹת רַבּוֹת אֶל שׁוּשַׁן הַבִּירָה אֶל יַד הֵגָי, וַתִּלָּקַח אֶסְתֵּר אֶל בֵּית הַמֶּלֶךְ אֶל יַד הֵגַי שֹׁמֵר הַנָּשִׁים: וַתִּיטַב הַנַּעֲרָה בְעֵינָיו וַתִּשָּׂא חֶסֶד לְפָנָיו, וַיְבַהֵל אֶת תַּמְרוּקֶיהָ וְאֶת מָנוֹתֶהָ לָתֵת לָהּ, וְאֵת שֶׁבַע הַנְּעָרוֹת הָרְאֻיוֹת לָתֶת לָהּ מִבֵּית הַמֶּלֶךְ, וַיְשַׁנֶּהָ וְאֶת נַעֲרוֹתֶיהָ לְטוֹב בֵּית הַנָּשִׁים: לֹא הִגִּידָה אֶסְתֵּר אֶת עַמָּהּ וְאֶת מוֹלַדְתָּהּ, כִּי מָרְדֳּכַי צִוָּה עָלֶיהָ אֲשֶׁר לֹא תַגִּיד: וּבְכָל יוֹם וָיוֹם מָרְדֳּכַי מִתְהַלֵּךְ לִפְנֵי חֲצַר בֵּית הַנָּשִׁים, לָדַעַת אֶת שְׁלוֹם אֶסְתֵּר וּמַה יֵּעָשֶׂה בָּהּ: וּבְהַגִּיעַ תֹּר נַעֲרָה וְנַעֲרָה לָבוֹא אֶל הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, מִקֵּץ הֱיוֹת לָהּ כְּדָת הַנָּשִׁים שְׁנֵים עָשָׂר חֹדֶשׁ כִּי כֵּן יִמְלְאוּ יְמֵי מְרוּקֵיהֶן, שִׁשָּׁה חֳדָשִׁים בְּשֶׁמֶן הַמֹּר וְשִׁשָּׁה חֳדָשִׁים בַּבְּשָׂמִים וּבְתַמְרוּקֵי הַנָּשִׁים: וּבָזֶה הַנַּעֲרָה בָּאָה אֶל הַמֶּלֶךְ, אֵת כָּל אֲשֶׁר תֹּאמַר יִנָּתֵן לָהּ לָבוֹא עִמָּהּ מִבֵּית הַנָּשִׁים עַד בֵּית הַמֶּלֶךְ: בָּעֶרֶב הִיא בָאָה וּבַבֹּקֶר הִיא שָׁבָה אֶל בֵּית הַנָּשִׁים שֵׁנִי, אֶל יַד שַׁעֲשְׁגַז סְרִיס הַמֶּלֶךְ שֹׁמֵר הַפִּילַגְשִׁים, לֹא תָבוֹא עוֹד אֶל הַמֶּלֶךְ כִּי אִם חָפֵץ בָּהּ הַמֶּלֶךְ וְנִקְרְאָה בְשֵׁם: וּבְהַגִּיעַ תֹּר אֶסְתֵּר בַּת אֲבִיחַיִל דֹּד מָרְדֳּכַי אֲשֶׁר לָקַח לוֹ לְבַת לָבוֹא אֶל הַמֶּלֶךְ, לֹא בִקְשָׁה דָּבָר כִּי אִם אֶת אֲשֶׁר יֹאמַר הֵגַי סְרִיס הַמֶּלֶךְ שֹׁמֵר הַנָּשִׁים, וַתְּהִי אֶסְתֵּר נֹשֵׂאת חֵן בְּעֵינֵי כָּל רֹאֶיהָ: וַתִּלָּקַח אֶסְתֵּר אֶל הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ אֶל בֵּית מַלְכוּתוֹ בַּחֹדֶשׁ הָעֲשִׂירִי הוּא חֹדֶשׁ טֵבֵת, בִּשְׁנַת שֶׁבַע לְמַלְכוּתוֹ: וַיֶּאֱהַב הַמֶּלֶךְ אֶת אֶסְתֵּר מִכָּל הַנָּשִׁים וַתִּשָּׂא חֵן וָחֶסֶד לְפָנָיו מִכָּל הַבְּתוּלֹת, וַיָּשֶׂם כֶּתֶר מַלְכוּת בְּרֹאשָׁהּ וַיַּמְלִיכֶהָ תַּחַת וַשְׁתִּי: וַיַּעַשׂ הַמֶּלֶךְ מִשְׁתֶּה גָדוֹל לְכָל שָׂרָיו וַעֲבָדָיו, אֵת מִשְׁתֵּה אֶסְתֵּר, וַהֲנָחָה לַמְּדִינוֹת עָשָׂה וַיִּתֵּן מַשְׂאֵת כְּיַד הַמֶּלֶךְ: וּבְהִקָּבֵץ בְּתוּלוֹת שֵׁנִית, וּמָרְדֳּכַי יֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ: אֵין אֶסְתֵּר מַגֶּדֶת מוֹלַדְתָּהּ וְאֶת עַמָּהּ כַּאֲשֶׁר צִוָּה עָלֶיהָ מָרְדֳּכַי, וְאֶת מַאֲמַר מָרְדֳּכַי אֶסְתֵּר עֹשָׂה כַּאֲשֶׁר הָיְתָה בְאָמְנָה אִתּוֹ: בַּיָּמִים הָהֵם, וּמָרְדֳּכַי יֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ, קָצַף בִּגְתָן וָתֶרֶשׁ שְׁנֵי סָרִיסֵי הַמֶּלֶךְ מִשֹּׁמְרֵי הַסַּף וַיְבַקְשׁוּ לִשְׁלֹחַ יָד בַּמֶּלֶךְ אֲחַשְׁוֵרֹשׁ: וַיִּוָּדַע הַדָּבָר לְמָרְדֳּכַי וַיַּגֵּד לְאֶסְתֵּר הַמַּלְכָּה, וַתֹּאמֶר אֶסְתֵּר לַמֶּלֶךְ בְּשֵׁם מָרְדֳּכַי: וַיְבֻקַּשׁ הַדָּבָר וַיִּמָּצֵא וַיִּתָּלוּ שְׁנֵיהֶם עַל עֵץ, וַיִּכָּתֵב בְּסֵפֶר דִּבְרֵי הַיָּמִים לִפְנֵי הַמֶּלֶךְ:","cond":["megilatEster"]},{"kind":"header","text":"פרק ג'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ג'","cond":["megilatEster"]},{"kind":"text","text":"אַחַר הַדְּבָרִים הָאֵלֶּה גִּדַּל הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ אֶת הָמָן בֶּן הַמְּדָתָא הָאֲגָגִי וַיְנַשְּׂאֵהוּ, וַיָּשֶׂם אֶת כִּסְאוֹ מֵעַל כָּל הַשָּׂרִים אֲשֶׁר אִתּוֹ: וְכָל עַבְדֵי הַמֶּלֶךְ אֲשֶׁר בְּשַׁעַר הַמֶּלֶךְ כֹּרְעִים וּמִשְׁתַּחֲוִים לְהָמָן, כִּי כֵן צִוָּה לוֹ הַמֶּלֶךְ, וּמָרְדֳּכַי לֹא יִכְרַע וְלֹא יִשְׁתַּחֲוֶה: וַיֹּאמְרוּ עַבְדֵי הַמֶּלֶךְ אֲשֶׁר בְּשַׁעַר הַמֶּלֶךְ לְמָרְדֳּכַי, מַדּוּעַ אַתָּה עוֹבֵר אֵת מִצְוַת הַמֶּלֶךְ: וַיְהִי כְּאָמְרָם אֵלָיו יוֹם וָיוֹם וְלֹא שָׁמַע אֲלֵיהֶם, וַיַּגִּידוּ לְהָמָן לִרְאוֹת הֲיַעַמְדוּ דִּבְרֵי מָרְדֳּכַי כִּי הִגִּיד לָהֶם אֲשֶׁר הוּא יְהוּדִי: וַיַּרְא הָמָן כִּי אֵין מָרְדֳּכַי כֹּרֵעַ וּמִשְׁתַּחֲוֶה לוֹ, וַיִּמָּלֵא הָמָן חֵמָה: וַיִּבֶז בְּעֵינָיו לִשְׁלֹח יָד בְּמָרְדֳּכַי לְבַדּוֹ כִּי הִגִּידוּ לוֹ אֶת עַם מָרְדֳּכַי, וַיְבַקֵּשׁ הָמָן לְהַשְׁמִיד אֶת כָּל הַיְּהוּדִים אֲשֶׁר בְּכָל מַלְכוּת אֲחַשְׁוֵרוֹשׁ עַם מָרְדֳּכַי: בַּחֹדֶשׁ הָרִאשׁוֹן הוּא חֹדֶשׁ נִיסָן בִּשְׁנַת שְׁתֵּים עֶשְׂרֵה לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, הִפִּיל פּוּר הוּא הַגּוֹרָל לִפְנֵי הָמָן מִיּוֹם לְיוֹם וּמֵחֹדֶשׁ לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר: וַיֹּאמֶר הָמָן לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ יֶשְׁנוֹ עַם אֶחָד מְפֻזָּר וּמְפֹרָד בֵּין הָעַמִּים בְּכֹל מְדִינוֹת מַלְכוּתֶךָ, וְדָתֵיהֶם שֹׁנוֹת מִכָּל עָם וְאֶת דָּתֵי הַמֶּלֶךְ אֵינָם עֹשִׂים וְלַמֶּלֶךְ אֵין שֹׁוֶה לְהַנִּיחָם: אִם עַל הַמֶּלֶךְ טוֹב יִכָּתֵב לְאַבְּדָם, וַעֲשֶׂרֶת אֲלָפִים כִּכַּר כֶּסֶף אֶשְׁקוֹל עַל יְדֵי עֹשֵׂי הַמְּלָאכָה לְהָבִיא אֶל גִּנְזֵי הַמֶּלֶךְ: וַיָּסַר הַמֶּלֶךְ אֶת טַבַּעְתּוֹ מֵעַל יָדוֹ, וַיִּתְּנָהּ לְהָמָן בֶּן הַמְּדָתָא הָאֲגָגִי צֹרֵר הַיְּהוּדִים: וַיֹּאמֶר הַמֶּלֶךְ לְהָמָן הַכֶּסֶף נָתוּן לָךְ, וְהָעָם לַעֲשׂוֹת בּוֹ כַּטּוֹב בְּעֵינֶיךָ: וַיִּקָּרְאוּ סֹפְרֵי הַמֶּלֶךְ בַּחֹדֶשׁ הָרִאשׁוֹן בִּשְׁלוֹשָׁה עָשָׂר יוֹם בּוֹ, וַיִּכָּתֵב כְּכָל אֲשֶׁר צִוָּה הָמָן אֶל אֲחַשְׁדַּרְפְּנֵי הַמֶּלֶךְ וְאֶל הַפַּחוֹת אֲשֶׁר עַל מְדִינָה וּמְדִינָה וְאֶל שָׂרֵי עַם וָעָם, מְדִינָה וּמְדִינָה כִּכְתָבָהּ וְעַם וָעָם כִּלְשׁוֹנוֹ, בְּשֵׁם הַמֶּלֶךְ אֲחַשְׁוֵרֹשׁ נִכְתָּב וְנֶחְתָּם בְּטַבַּעַת הַמֶּלֶךְ: וְנִשְׁלוֹחַ סְפָרִים בְּיַד הָרָצִים אֶל כָּל מְדִינוֹת הַמֶּלֶךְ, לְהַשְׁמִיד לַהֲרֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלוֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: פַּתְשֶׁגֶן הַכְּתָב לְהִנָּתֵן דָּת בְּכָל מְדִינָה וּמְדִינָה גָּלוּי לְכָל הָעַמִּים, לִהְיוֹת עֲתִדִים לַיּוֹם הַזֶּה: הָרָצִים יָצְאוּ דְחוּפִים בִּדְבַר הַמֶּלֶךְ וְהַדָּת נִתְּנָה בְּשׁוּשַׁן הַבִּירָה, וְהַמֶּלֶךְ וְהָמָן יָשְׁבוּ לִשְׁתּוֹת וְהָעִיר שׁוּשָׁן נָבוֹכָה:","cond":["megilatEster"]},{"kind":"header","text":"פרק ד'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ד'","cond":["megilatEster"]},{"kind":"text","text":"וּמָרְדֳּכַי יָדַע אֶת כָּל אֲשֶׁר נַעֲשָׂה וַיִּקְרַע מָרְדֳּכַי אֶת בְּגָדָיו וַיִּלְבַּשׁ שַׂק וָאֵפֶר, וַיֵּצֵא בְּתוֹךְ הָעִיר וַיִּזְעַק זְעָקָה גְדֹלָה וּמָרָה: וַיָּבוֹא עַד לִפְנֵי שַׁעַר הַמֶּלֶךְ, כִּי אֵין לָבוֹא אֶל שַׁעַר הַמֶּלֶךְ בִּלְבוּשׁ שָׂק: וּבְכָל מְדִינָה וּמְדִינָה מְקוֹם אֲשֶׁר דְּבַר הַמֶּלֶךְ וְדָתוֹ מַגִּיעַ, אֵבֶל גָּדוֹל לַיְּהוּדִים וְצוֹם וּבְכִי וּמִסְפֵּד, שַׂק וָאֵפֶר יֻצַּע לָרַבִּים: וַתָּבוֹאנָה נַעֲרוֹת אֶסְתֵּר וְסָרִיסֶיהָ וַיַּגִּידוּ לָהּ וַתִּתְחַלְחַל הַמַּלְכָּה מְאֹד, וַתִּשְׁלַח בְּגָדִים לְהַלְבִּישׁ אֶת מָרְדֳּכַי וּלְהָסִיר שַׂקּוֹ מֵעָלָיו וְלֹא קִבֵּל: וַתִּקְרָא אֶסְתֵּר לַהֲתָךְ מִסָּרִיסֵי הַמֶּלֶךְ אֲשֶׁר הֶעֱמִיד לְפָנֶיהָ וַתְּצַוֵּהוּ עַל מָרְדֳּכַי, לָדַעַת מַה זֶּה וְעַל מַה זֶּה: וַיֵּצֵא הֲתָךְ אֶל מָרְדֳּכַי, אֶל רְחוֹב הָעִיר אֲשֶׁר לִפְנֵי שַׁעַר הַמֶּלֶךְ: וַיַּגֶּד לוֹ מָרְדֳּכַי אֵת כָּל אֲשֶׁר קָרָהוּ, וְאֵת פָּרָשַׁת הַכֶּסֶף אֲשֶׁר אָמַר הָמָן לִשְׁקוֹל עַל גִּנְזֵי הַמֶּלֶךְ בַּיְּהוּדִים לְאַבְּדָם: וְאֶת פַּתְשֶׁגֶן כְּתָב הַדָּת אֲשֶׁר נִתַּן בְּשׁוּשָׁן לְהַשְׁמִידָם נָתַן לוֹ לְהַרְאוֹת אֶת אֶסְתֵּר וּלְהַגִּיד לָהּ, וּלְצַוּוֹת עָלֶיהָ לָבוֹא אֶל הַמֶּלֶךְ לְהִתְחַנֶּן לוֹ וּלְבַקֵּשׁ מִלְּפָנָיו עַל עַמָּהּ: וַיָּבוֹא הֲתָךְ, וַיַּגֵּד לְאֶסְתֵּר אֵת דִּבְרֵי מָרְדֳּכַי: וַתֹּאמֶר אֶסְתֵּר לַהֲתָךְ, וַתְּצַוֵּהוּ אֶל מָרְדֳּכַי: כָּל עַבְדֵי הַמֶּלֶךְ וְעַם מְדִינוֹת הַמֶּלֶךְ יוֹדְעִים אֲשֶׁר כָּל אִישׁ וְאִשָּׁה אֲשֶׁר יָבוֹא אֶל הַמֶּלֶךְ אֶל הֶחָצֵר הַפְּנִימִית אֲשֶׁר לֹא יִקָּרֵא אַחַת דָּתוֹ לְהָמִית, לְבַד מֵאֲשֶׁר יוֹשִׁיט לוֹ הַמֶּלֶךְ אֶת שַׁרְבִיט הַזָּהָב וְחָיָה, וַאֲנִי לֹא נִקְרֵאתִי לָבוֹא אֶל הַמֶּלֶךְ זֶה שְׁלוֹשִׁים יוֹם: וַיַּגִּידוּ לְמָרְדֳּכַי אֵת דִּבְרֵי אֶסְתֵּר: וַיֹּאמֶר מָרְדֳּכַי לְהָשִׁיב אֶל אֶסְתֵּר, אַל תְּדַמִּי בְנַפְשֵׁךְ לְהִמָּלֵט בֵּית הַמֶּלֶךְ מִכָּל הַיְּהוּדִים: כִּי אִם הַחֲרֵשׁ תַּחֲרִישִׁי בָּעֵת הַזֹּאת, רֶוַח וְהַצָּלָה יַעֲמוֹד לַיְּהוּדִים מִמָּקוֹם אַחֵר וְאַתְּ וּבֵית אָבִיךְ תֹּאבֵדוּ, וּמִי יוֹדֵעַ אִם לְעֵת כָּזֹאת הִגַּעַתְּ לַמַּלְכוּת: וַתֹּאמֶר אֶסְתֵּר לְהָשִׁיב אֶל מָרְדֳּכַי: לֵךְ כְּנוֹס אֶת כָּל הַיְּהוּדִים הַנִּמְצְאִים בְּשׁוּשָׁן וְצוּמוּ עָלַי וְאַל תֹּאכְלוּ וְאַל תִּשְׁתּוּ שְׁלֹשֶׁת יָמִים לַיְלָה וָיוֹם, גַּם אֲנִי וְנַעֲרֹתַי אָצוּם כֵּן, וּבְכֵן אָבוֹא אֶל הַמֶּלֶךְ אֲשֶׁר לֹא כַדָּת וְכַאֲשֶׁר אָבַדְתִּי אָבָדְתִּי: וַיַּעֲבֹר מָרְדֳּכַי, וַיַּעַשׂ כְּכֹל אֲשֶׁר צִוְּתָה עָלָיו אֶסְתֵּר:","cond":["megilatEster"]},{"kind":"header","text":"פרק ה'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ה'","cond":["megilatEster"]},{"kind":"text","text":"וַיְהִי בַּיּוֹם הַשְּׁלִישִׁי וַתִּלְבַּשׁ אֶסְתֵּר מַלְכוּת, וַתַּעֲמֹד בַּחֲצַר בֵּית הַמֶּלֶךְ הַפְּנִימִית נֹכַח בֵּית הַמֶּלֶךְ, וְהַמֶּלֶךְ יוֹשֵׁב עַל כִּסֵּא מַלְכוּתוֹ בְּבֵית הַמַּלְכוּת נֹכַח פֶּתַח הַבָּיִת: וַיְהִי כִרְאוֹת הַמֶּלֶךְ אֶת אֶסְתֵּר הַמַּלְכָּה עֹמֶדֶת בֶּחָצֵר נָשְׂאָה חֵן בְּעֵינָיו, וַיּוֹשֶׁט הַמֶּלֶךְ לְאֶסְתֵּר אֶת שַׁרְבִיט הַזָּהָב אֲשֶׁר בְּיָדוֹ, וַתִּקְרַב אֶסְתֵּר וַתִּגַּע בְּרֹאשׁ הַשַּׁרְבִיט: וַיֹּאמֶר לָהּ הַמֶּלֶךְ מַה לָּךְ אֶסְתֵּר הַמַּלְכָּה, וּמַה בַּקָּשָׁתֵךְ עַד חֲצִי הַמַּלְכוּת וְיִנָּתֵן לָךְ: וַתֹּאמֶר אֶסְתֵּר אִם עַל הַמֶּלֶךְ טוֹב, יָבוֹא הַמֶּלֶךְ וְהָמָן הַיּוֹם אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשִׂיתִי לוֹ: וַיֹּאמֶר הַמֶּלֶךְ מַהֲרוּ אֶת הָמָן לַעֲשׂוֹת אֶת דְּבַר אֶסְתֵּר, וַיָּבֹא הַמֶּלֶךְ וְהָמָן אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשְׂתָה אֶסְתֵּר: וַיֹּאמֶר הַמֶּלֶךְ לְאֶסְתֵּר בְּמִשְׁתֵּה הַיַּיִן מַה שְּׁאֵלָתֵךְ וְיִנָּתֵן לָךְ, וּמַה בַּקָּשָׁתֵךְ עַד חֲצִי הַמַּלְכוּת וְתֵעָשׂ: וַתַּעַן אֶסְתֵּר וַתֹּאמַר, שְׁאֵלָתִי וּבַקָּשָׁתִי: אִם מָצָאתִי חֵן בְּעֵינֵי הַמֶּלֶךְ וְאִם עַל הַמֶּלֶךְ טוֹב לָתֵת אֶת שְׁאֵלָתִי וְלַעֲשׂוֹת אֶת בַּקָּשָׁתִי, יָבוֹא הַמֶּלֶךְ וְהָמָן אֶל הַמִּשְׁתֶּה אֲשֶׁר אֶעֱשֶׂה לָהֶם וּמָחָר אֶעֱשֶׂה כִּדְבַר הַמֶּלֶךְ: וַיֵּצֵא הָמָן בַּיּוֹם הַהוּא שָׂמֵחַ וְטוֹב לֵב, וְכִרְאוֹת הָמָן אֶת מָרְדֳּכַי בְּשַׁעַר הַמֶּלֶךְ וְלֹא קָם וְלֹא זָע מִמֶּנּוּ וַיִּמָּלֵא הָמָן עַל מָרְדֳּכַי חֵמָה: וַיִּתְאַפַּק הָמָן וַיָּבוֹא אֶל בֵּיתוֹ, וַיִּשְׁלַח וַיָּבֵא אֶת אֹהֲבָיו וְאֶת זֶרֶשׁ אִשְׁתּוֹ: וַיְסַפֵּר לָהֶם הָמָן אֶת כְּבוֹד עָשְׁרוֹ וְרֹב בָּנָיו, וְאֵת כָּל אֲשֶׁר גִּדְּלוֹ הַמֶּלֶךְ וְאֵת אֲשֶׁר נִשְּׂאוֹ עַל הַשָּׂרִים וְעַבְדֵי הַמֶּלֶךְ: וַיֹּאמֶר הָמָן, אַף לֹא הֵבִיאָה אֶסְתֵּר הַמַּלְכָּה עִם הַמֶּלֶךְ אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשָׂתָה כִּי אִם אוֹתִי, וְגַם לְמָחָר אֲנִי קָרוּא לָהּ עִם הַמֶּלֶךְ: וְכָל זֶה אֵינֶנּוּ שֹׁוֶה לִי, בְּכָל עֵת אֲשֶׁר אֲנִי רֹאֶה אֶת מָרְדֳּכַי הַיְּהוּדִי יוֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ: וַתֹּאמֶר לוֹ זֶרֶשׁ אִשְׁתּוֹ וְכָל אֹהֲבָיו יַעֲשׂוּ עֵץ גָּבֹהַּ חֲמִשִּׁים אַמָּה, וּבַבֹּקֶר אֱמֹר לַמֶּלֶךְ וְיִתְלוּ אֶת מָרְדֳּכַי עָלָיו וּבֹא עִם הַמֶּלֶךְ אֶל הַמִּשְׁתֶּה שָׂמֵחַ, וַיִּיטַב הַדָּבָר לִפְנֵי הָמָן וַיַּעַשׂ הָעֵץ:","cond":["megilatEster"]},{"kind":"header","text":"פרק ו'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ו'","cond":["megilatEster"]},{"kind":"special","text":"בַּלַּיְלָה הַהוּא נָדְדָה שְׁנַת הַמֶּלֶךְ, וַיֹּאמֶר לְהָבִיא אֶת סֵפֶר הַזִּכְרֹנוֹת דִּבְרֵי הַיָּמִים, וַיִּהְיוּ נִקְרָאִים לִפְנֵי הַמֶּלֶךְ:","cond":["megilatEster"]},{"kind":"text","text":"וַיִּמָּצֵא כָתוּב אֲשֶׁר הִגִּיד מָרְדֳּכַי עַל בִּגְתָנָא וָתֶרֶשׁ שְׁנֵי סָרִיסֵי הַמֶּלֶךְ מִשֹּׁמְרֵי הַסַּף אֲשֶׁר בִּקְשׁוּ לִשְׁלֹחַ יָד בַּמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: וַיֹּאמֶר הַמֶּלֶךְ מַה נַּעֲשָׂה יְקָר וּגְדוּלָּה לְמָרְדֳּכַי עַל זֶה, וַיֹּאמְרוּ נַעֲרֵי הַמֶּלֶךְ מְשָׁרְתָיו לֹא נַעֲשָׂה עִמּוֹ דָּבָר: וַיֹּאמֶר הַמֶּלֶךְ מִי בֶחָצֵר, וְהָמָן בָּא לַחֲצַר בֵּית הַמֶּלֶךְ הַחִיצוֹנָה לֵאמֹר לַמֶּלֶךְ לִתְלוֹת אֶת מָרְדֳּכַי עַל הָעֵץ אֲשֶׁר הֵכִין לוֹ: וַיֹּאמְרוּ נַעֲרֵי הַמֶּלֶךְ אֵלָיו הִנֵּה הָמָן עֹמֵד בֶּחָצֵר, וַיֹּאמֶר הַמֶּלֶךְ יָבוֹא: וַיָּבוֹא הָמָן, וַיֹּאמֶר לוֹ הַמֶּלֶךְ מַה לַעֲשׂוֹת בָּאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ, וַיֹּאמֶר הָמָן בְּלִבּוֹ לְמִי יַחְפֹּץ הַמֶּלֶךְ לַעֲשׂוֹת יְקָר יוֹתֵר מִמֶּנִּי: וַיֹּאמֶר הָמָן אֶל הַמֶּלֶךְ, אִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ: יָבִיאוּ לְבוּשׁ מַלְכוּת אֲשֶׁר לָבַשׁ בּוֹ הַמֶּלֶךְ, וְסוּס אֲשֶׁר רָכַב עָלָיו הַמֶּלֶךְ וַאֲשֶׁר נִתַּן כֶּתֶר מַלְכוּת בְּרֹאשׁוֹ: וְנָתוֹן הַלְּבוּשׁ וְהַסּוּס עַל יַד אִישׁ מִשָּׂרֵי הַמֶּלֶךְ הַפַּרְתְּמִים וְהִלְבִּישׁוּ אֶת הָאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ, וְהִרְכִּיבֻהוּ עַל הַסּוּס בִּרְחוֹב הָעִיר וְקָרְאוּ לְפָנָיו כָּכָה יֵעָשֶׂה לָאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ: וַיֹּאמֶר הַמֶּלֶךְ לְהָמָן מַהֵר קַח אֶת הַלְּבוּשׁ וְאֶת הַסּוּס כַּאֲשֶׁר דִּבַּרְתָּ וַעֲשֵׂה כֵן לְמָרְדֳּכַי הַיְּהוּדִי הַיּוֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ, אַל תַּפֵּל דָּבָר מִכֹּל אֲשֶׁר דִּבַּרְתָּ: וַיִּקַּח הָמָן אֶת הַלְּבוּשׁ וְאֶת הַסּוּס וַיַּלְבֵּשׁ אֶת מָרְדֳּכַי, וַיַּרְכִּיבֵהוּ בִּרְחוֹב הָעִיר וַיִּקְרָא לְפָנָיו כָּכָה יֵעָשֶׂה לָאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ: וַיָּשָָב מָרְדֳּכַי אֶל שַׁעַר הַמֶּלֶךְ, וְהָמָן נִדְחַף אֶל בֵּיתוֹ אָבֵל וַחֲפוּי רֹאשׁ: וַיְסַפֵּר הָמָן לְזֶרֶשׁ אִשְׁתּוֹ וּלְכָל אֹהֲבָיו אֵת כָּל אֲשֶׁר קָרָהוּ, וַיֹּאמְרוּ לּוֹ חֲכָמָיו וְזֶרֶשׁ אִשְׁתּוֹ אִם מִזֶּרַע הַיְּהוּדִים מָרְדֳּכַי אֲשֶׁר הַחִלּוֹתָ לִנְפֹּל לְפָנָיו לֹא תוּכַל לוֹ, כִּי נָפוֹל תִּפּוֹל לְפָנָיו: עוֹדָם מְדַבְּרִים עִמּוֹ וְסָרִיסֵי הַמֶּלֶךְ הִגִּיעוּ, וַיַּבְהִלוּ לְהָבִיא אֶת הָמָן אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשְׂתָה אֶסְתֵּר:","cond":["megilatEster"]},{"kind":"header","text":"פרק ז'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ז'","cond":["megilatEster"]},{"kind":"text","text":"וַיָּבֹא הַמֶּלֶךְ וְהָמָן לִשְׁתּוֹת עִם אֶסְתֵּר הַמַּלְכָּה: וַיֹּאמֶר הַמֶּלֶךְ לְאֶסְתֵּר גַּם בַּיּוֹם הַשֵּׁנִי בְּמִשְׁתֵּה הַיַּיִן מַה שְּׁאֵלָתֵךְ אֶסְתֵּר הַמַּלְכָּה וְתִנָּתֵן לָךְ, וּמַה בַּקָּשָׁתֵךְ עַד חֲצִי הַמַּלְכוּת וְתֵעָשׂ: וַתַּעַן אֶסְתֵּר הַמַּלְכָּה וַתֹּאמַר אִם מָצָאתִי חֵן בְּעֵינֶיךָ הַמֶּלֶךְ וְאִם עַל הַמֶּלֶךְ טוֹב, תִּנָּתֶן לִי נַפְשִׁי בִּשְׁאֵלָתִי וְעַמִּי בְּבַקָּשָׁתִי: כִּי נִמְכַּרְנוּ אֲנִי וְעַמִּי לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד, וְאִלּוּ לַעֲבָדִים וְלִשְׁפָחוֹת נִמְכַּרְנוּ הֶחֱרַשְׁתִּי כִּי אֵין הַצָּר שֹׁוֶה בְּנֵזֶק הַמֶּלֶךְ: וַיֹּאמֶר הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ וַיֹּאמֶר לְאֶסְתֵּר הַמַּלְכָּה, מִי הוּא זֶה וְאֵי זֶה הוּא אֲשֶׁר מְלָאוֹ לִבּוֹ לַעֲשׂוֹת כֵּן: וַתֹּאמֶר אֶסְתֵּר אִישׁ צַר וְאוֹיֵב הָמָן הָרָע הַזֶּה, וְהָמָן נִבְעַת מִלִּפְנֵי הַמֶּלֶךְ וְהַמַּלְכָּה: וְהַמֶּלֶךְ קָם בַּחֲמָתוֹ מִמִּשְׁתֵּה הַיַּיִן אֶל גִּנַּת הַבִּיתָן, וְהָמָן עָמַד לְבַקֵּשׁ עַל נַפְשׁוֹ מֵאֶסְתֵּר הַמַּלְכָּה כִּי רָאָה כִּי כָלְתָה אֵלָיו הָרָעָה מֵאֵת הַמֶּלֶךְ: וְהַמֶּלֶךְ שָׁב מִגִּנַּת הַבִּיתָן אֶל בֵּית מִשְׁתֵּה הַיַּיִן וְהָמָן נֹפֵל עַל הַמִּטָּה אֲשֶׁר אֶסְתֵּר עָלֶיהָ, וַיֹּאמֶר הַמֶּלֶךְ הֲגַם לִכְבּוֹשׁ אֶת הַמַּלְכָּה עִמִּי בַּבָּיִת, הַדָּבָר יָצָא מִפִּי הַמֶּלֶךְ וּפְנֵי הָמָן חָפוּ: וַיֹּאמֶר חַרְבוֹנָה אֶחָד מִן הַסָּרִיסִים לִפְנֵי הַמֶּלֶךְ גַּם הִנֵּה הָעֵץ אֲשֶׁר עָשָׂה הָמָן לְמָרְדֳּכַי אֲשֶׁר דִּבֶּר טוֹב עַל הַמֶּלֶךְ עֹמֵד בְּבֵית הָמָן גָּבֹהַּ חֲמִשִּׁים אַמָּה, וַיֹּאמֶר הַמֶּלֶךְ תְּלֻהוּ עָלָיו: וַיִּתְלוּ אֶת הָמָן עַל הָעֵץ אֲשֶׁר הֵכִין לְמָרְדֳּכַי, וַחֲמַת הַמֶּלֶךְ שָׁכָכָה:","cond":["megilatEster"]},{"kind":"header","text":"פרק ח'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ח'","cond":["megilatEster"]},{"kind":"text","text":"בַּיּוֹם הַהוּא נָתַן הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ לְאֶסְתֵּר הַמַּלְכָּה אֶת בֵּית הָמָן צֹרֵר הַיְּהוּדִים, וּמָרְדֳּכַי בָּא לִפְנֵי הַמֶּלֶךְ כִּי הִגִּידָה אֶסְתֵּר מַה הוּא לָהּ: וַיָּסַר הַמֶּלֶךְ אֶת טַבַּעְתּוֹ אֲשֶׁר הֶעֱבִיר מֵהָמָן וַיִּתְּנָהּ לְמָרְדֳּכַי, וַתָּשֶׂם אֶסְתֵּר אֶת מָרְדֳּכַי עַל בֵּית הָמָן: וַתּוֹסֶף אֶסְתֵּר וַתְּדַבֵּר לִפְנֵי הַמֶּלֶךְ וַתִּפֹּל לִפְנֵי רַגְלָיו, וַתֵּבְךְּ וַתִּתְחַנֶּן לוֹ לְהַעֲבִיר אֶת רָעַת הָמָן הָאֲגָגִי וְאֵת מַחֲשַׁבְתּוֹ אֲשֶׁר חָשַׁב עַל הַיְּהוּדִים: וַיּוֹשֶׁט הַמֶּלֶךְ לְאֶסְתֵּר אֵת שַׁרְבִט הַזָּהָב, וַתָּקָם אֶסְתֵּר וַתַּעֲמֹד לִפְנֵי הַמֶּלֶךְ: וַתֹּאמֶר אִם עַל הַמֶּלֶךְ טוֹב וְאִם מָצָאתִי חֵן לְפָנָיו וְכָשֵׁר הַדָּבָר לִפְנֵי הַמֶּלֶךְ וְטוֹבָה אֲנִי בְּעֵינָיו, יִכָּתֵב לְהָשִׁיב אֶת הַסְּפָרִים מַחֲשֶׁבֶת הָמָן בֶּן הַמְּדָתָא הָאֲגָגִי אֲשֶׁר כָּתַב לְאַבֵּד אֶת הַיְּהוּדִים אֲשֶׁר בְּכָל מְדִינוֹת הַמֶּלֶךְ: כִּי אֵיכָכָה אוּכַל וְרָאִיתִי בָּרָעָה אֲשֶׁר יִמְצָא אֶת עַמִּי, וְאֵיכָכָה אוּכַל וְרָאִיתִי בְּאָבְדַן מוֹלַדְתִּי: וַיֹּאמֶר הַמֶּלֶךְ אֲחַשְׁוֵרֹשׁ לְאֶסְתֵּר הַמַּלְכָּה וּלְמָרְדֳּכַי הַיְּהוּדִי, הִנֵּה בֵית הָמָן נָתַתִּי לְאֶסְתֵּר וְאֹתוֹ תָּלוּ עַל הָעֵץ עַל אֲשֶׁר שָׁלַח יָדוֹ בַּיְּהוּדִים: וְאַתֶּם כִּתְבוּ עַל הַיְּהוּדִים כַּטּוֹב בְּעֵינֵיכֶם בְּשֵׁם הַמֶּלֶךְ וְחִתְמוּ בְּטַבַּעַת הַמֶּלֶךְ, כִּי כְתָב אֲשֶׁר נִכְתָּב בְּשֵׁם הַמֶּלֶךְ וְנַחְתּוֹם בְּטַבַּעַת הַמֶּלֶךְ אֵין לְהָשִׁיב: וַיִּקָּרְאוּ סֹפְרֵי הַמֶּלֶךְ בָּעֵת הַהִיא בַּחֹדֶשׁ הַשְּׁלִישִׁי הוּא חֹדֶשׁ סִיוָן בִּשְׁלוֹשָׁה וְעֶשְׂרִים בּוֹ, וַיִּכָּתֵב כְּכָל אֲשֶׁר צִוָּה מָרְדֳּכַי אֶל הַיְּהוּדִים וְאֶל הָאֲחַשְׁדַּרְפְּנִים וְהַפַּחוֹת וְשָׂרֵי הַמְּדִינוֹת אֲשֶׁר מֵהֹדּוּ וְעַד כּוּשׁ, שֶׁבַע וְעֶשְׂרִים וּמֵאָה מְדִינָה, מְדִינָה וּמְדִינָה כִּכְתָבָהּ וְעַם וָעָם כִּלְשֹׁנוֹ, וְאֶל הַיְּהוּדִים כִּכְתָבָם וְכִלְשׁוֹנָם: וַיִּכְתֹּב בְּשֵׁם הַמֶּלֶךְ אֲחַשְׁוֵרֹשׁ וַיַּחְתֹּם בְּטַבַּעַת הַמֶּלֶךְ, וַיִּשְׁלַח סְפָרִים בְּיַד הָרָצִים בַּסּוּסִים רֹכְבֵי הָרֶכֶשׁ הָאֲחַשְׁתְּרָנִים בְּנֵי הָרַמָּכִים: אֲשֶׁר נָתַן הַמֶּלֶךְ לַיְּהוּדִים אֲשֶׁר בְּכָל עִיר וָעִיר לְהִקָּהֵל וְלַעֲמֹד עַל נַפְשָׁם, לְהַשְׁמִיד וְלַהֲרֹג וּלְאַבֵּד אֶת כָּל חֵיל עַם וּמְדִינָה הַצָּרִים אֹתָם טַף וְנָשִׁים, וּשְׁלָלָם לָבוֹז: בְּיוֹם אֶחָד בְּכָל מְדִינוֹת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, בִּשְׁלוֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר: פַּתְשֶׁגֶן הַכְּתָב לְהִנָּתֵן דָּת בְּכָל מְדִינָה וּמְדִינָה גָּלוּי לְכָל הָעַמִּים, וְלִהְיוֹת הַיְּהוּדִים עֲתִידִים לַיּוֹם הַזֶּה לְהִנָּקֵם מֵאֹיְבֵיהֶם: הָרָצִים רֹכְבֵי הָרֶכֶשׁ הָאֲחַשְׁתְּרָנִים יָצְאוּ מְבֹהָלִים וּדְחוּפִים בִּדְבַר הַמֶּלֶךְ, וְהַדָּת נִתְּנָה בְּשׁוּשַׁן הַבִּירָה:","cond":["megilatEster"]},{"kind":"special","text":"וּמָרְדֳּכַי יָצָא מִלִּפְנֵי הַמֶּלֶךְ בִּלְבוּשׁ מַלְכוּת תְּכֵלֶת וָחוּר וַעֲטֶרֶת זָהָב גְּדוֹלָה וְתַכְרִיךְ בּוּץ וְאַרְגָּמָן, וְהָעִיר שׁוּשָׁן צָהֲלָה וְשָׂמֵחָה: לַיְּהוּדִים הָיְתָה אוֹרָה וְשִׂמְחָה, וְשָׂשֹׂן וִיקָר:","cond":["megilatEster"]},{"kind":"text","text":"וּבְכָל מְדִינָה וּמְדִינָה וּבְכָל עִיר וָעִיר, מְקוֹם אֲשֶׁר דְּבַר הַמֶּלֶךְ וְדָתוֹ מַגִּיעַ, שִׂמְחָה וְשָׂשׂוֹן לַיְּהוּדִים מִשְׁתֶּה וְיוֹם טוֹב, וְרַבִּים מֵעַמֵּי הָאָרֶץ מִתְיַהֲדִים כִּי נָפַל פַּחַד הַיְּהוּדִים עֲלֵיהֶם:","cond":["megilatEster"]},{"kind":"header","text":"פרק ט'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ט'","cond":["megilatEster"]},{"kind":"text","text":"וּבִשְׁנֵים עָשָׂר חֹדֶשׁ הוּא חֹדֶשׁ אֲדָר בִּשְׁלוֹשָׁה עָשָׂר יוֹם בּוֹ אֲשֶׁר הִגִּיעַ דְּבַר הַמֶּלֶךְ וְדָתוֹ לְהֵעָשׂוֹת, בַּיּוֹם אֲשֶׁר שִׂבְּרוּ אֹיְבֵי הַיְּהוּדִים לִשְׁלוֹט בָּהֶם וְנַהֲפוֹךְ הוּא אֲשֶׁר יִשְׁלְטוּ הַיְּהוּדִים הֵמָּה בְּשֹׂנְאֵיהֶם: נִקְהֲלוּ הַיְּהוּדִים בְּעָרֵיהֶם בְּכָל מְדִינוֹת הַמֶּלֶךְ אֳחַשְׁוֵרוֹשׁ לִשְׁלֹחַ יָד בִּמְבַקְשֵׁי רָעָתָם, וְאִישׁ לֹא עָמַד לִפְנֵיהֶם כִּי נָפַל פַּחְדָּם עַל כָּל הָעַמִּים: וְכָל שָׂרֵי הַמְּדִינוֹת וְהָאֲחַשְׁדַּרְפְּנִים וְהַפַּחוֹת וְעֹשֵׂי הַמְּלָאכָה אֲשֶׁר לַמֶּלֶךְ מְנַשְּׂאִים אֶת הַיְּהוּדִים, כִּי נָפַל פַּחַד מָרְדֳּכַי עֲלֵיהֶם: כִּי גָדוֹל מָרְדֳּכַי בְּבֵית הַמֶּלֶךְ וְשָׁמְעוֹ הוֹלֵךְ בְּכָל הַמְּדִינוֹת, כִּי הָאִישׁ מָרְדֳּכַי הוֹלֵךְ וְגָדוֹל: וַיַּכּוּ הַיְּהוּדִים בְּכָל אֹיְבֵיהֶם מַכַּת חֶרֶב וְהֶרֶג וְאַבְדָן, וַיַּעֲשׂוּ בְשֹׂנְאֵיהֶם כִּרְצוֹנָם: וּבְשׁוּשַׁן הַבִּירָה הָרְגוּ הַיְּהוּדִים וְאַבֵּד חֲמֵשׁ מֵאוֹת אִישׁ: וְאֵת פַּרְשַׁנְדָּתָא וְאֵת דַּלְפוֹן וְאֵת אַסְפָּתָא: וְאֵת פּוֹרָתָא וְאֵת אֲדַלְיָא וְאֵת אֲרִידָתָא: וְאֵת פַּרְמַשְׁתָּא וְאֵת אֲרִיסַי וְאֵת אֲרִדַי וְאֵת וַיְזָתָא: עֲשֶׂרֶת בְּנֵי הָמָן בֶּן הַמְּדָתָא צֹרֵר הַיְּהוּדִים הָרָגוּ, וּבַבִּזָּה לֹא שָׁלְחוּ אֶת יָדָם: בַּיּוֹם הַהוּא בָּא מִסְפַּר הַהֲרוּגִים בְּשׁוּשַׁן הַבִּירָה לִפְנֵי הַמֶּלֶךְ: וַיֹּאמֶר הַמֶּלֶךְ לְאֶסְתֵּר הַמַּלְכָּה בְּשׁוּשַׁן הַבִּירָה הָרְגוּ הַיְּהוּדִים וְאַבֵּד חֲמֵשׁ מֵאוֹת אִישׁ וְאֵת עֲשֶׂרֶת בְּנֵי הָמָן, בִּשְׁאָר מְדִינוֹת הַמֶּלֶךְ מֶה עָשׂוּ, וּמַה שְּׁאֵלָתֵךְ וְיִנָּתֵן לָךְ וּמַה בַּקָּשָׁתֵךְ עוֹד וְתֵעָשׂ: וַתֹּאמֶר אֶסְתֵּר אִם עַל הַמֶּלֶךְ טוֹב, יִנָּתֵן גַּם מָחָר לַיְּהוּדִים אֲשֶׁר בְּשׁוּשָׁן לַעֲשׂוֹת כְּדָת הַיּוֹם, וְאֵת עֲשֶׂרֶת בְּנֵי הָמָן יִתְלוּ עַל הָעֵץ: וַיֹּאמֶר הַמֶּלֶךְ לְהֵעָשׂוֹת כֵּן וַתִּנָּתֵן דָּת בְּשׁוּשָׁן, וְאֵת עֲשֶׂרֶת בְּנֵי הָמָן תָּלוּ: וַיִּקָּהֲלוּ הַיְּהוּדִים אֲשֶׁר בְּשׁוּשָׁן גַּם בְּיוֹם אַרְבָּעָה עָשָׂר לְחֹדֶשׁ אֲדָר וַיַּהַרְגוּ בְשׁוּשָׁן שְׁלֹשׁ מֵאוֹת אִישׁ, וּבַבִּזָּה לֹא שָׁלְחוּ אֶת יָדָם: וּשְׁאָר הַיְּהוּדִים אֲשֶׁר בִּמְדִינוֹת הַמֶּלֶךְ נִקְהֲלוּ וְעָמֹד עַל נַפְשָׁם וְנוֹחַ מֵאֹיְבֵיהֶם וְהָרֹג בְּשֹׂנְאֵיהֶם חֲמִשָּׁה וְשִׁבְעִים אָלֶף, וּבַבִּזָּה לֹא שָׁלְחוּ אֶת יָדָם: בְּיוֹם שְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ אֲדָר, וְנוֹחַ בְּאַרְבָּעָה עָשָׂר בּוֹ וְעָשֹׂה אֹתוֹ יוֹם מִשְׁתֶּה וְשִׂמְחָה: וְהַיְּהוּדִים אֲשֶׁר בְּשׁוּשָׁן נִקְהֲלוּ בִּשְׁלֹשָׁה עָשָׂר בּוֹ וּבְאַרְבָּעָה עָשָׂר בּוֹ, וְנוֹחַ בַּחֲמִשָּׁה עָשָׂר בּוֹ וְעָשֹׂה אֹתוֹ יוֹם מִשְׁתֶּה וְשִׂמְחָה: עַל כֵּן הַיְּהוּדִים הַפְּרָזִים הַיֹּשְׁבִים בְּעָרֵי הַפְּרָזוֹת, עֹשִׂים אֵת יוֹם אַרְבָּעָה עָשָׂר לְחֹדֶשׁ אֲדָר שִׂמְחָה וּמִשְׁתֶּה וְיוֹם טוֹב, וּמִשְׁלוֹחַ מָנוֹת אִישׁ לְרֵעֵהוּ: וַיִּכְתֹּב מָרְדֳּכַי אֶת הַדְּבָרִים הָאֵלֶּה, וַיִּשְׁלַח סְפָרִים אֶל כָּל הַיְּהוּדִים אֲשֶׁר בְּכָל מְדִינוֹת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ הַקְּרוֹבִים וְהָרְחוֹקִים: לְקַיֵּם עֲלֵיהֶם, לִהְיוֹת עֹשִׂים אֵת יוֹם אַרְבָּעָה עָשָׂר לְחֹדֶשׁ אֲדָר וְאֵת יוֹם חֲמִשָּׁה עָשָׂר בּוֹ, בְּכָל שָׁנָה וְשָׁנָה: כַּיָּמִים אֲשֶׁר נָחוּ בָהֶם הַיְּהוּדִים מֵאוֹיְבֵיהֶם, וְהַחֹדֶשׁ אֲשֶׁר נֶהְפַּךְ לָהֶם מִיָּגוֹן לְשִׂמְחָה וּמֵאֵבֶל לְיוֹם טוֹב, לַעֲשׂוֹת אוֹתָם יְמֵי מִשְׁתֶּה וְשִׂמְחָה וּמִשְׁלוֹחַ מָנוֹת אִישׁ לְרֵעֵהוּ וּמַתָּנוֹת לָאֶבְיוֹנִים: וְקִבֵּל הַיְּהוּדִים אֵת אֲשֶׁר הֵחֵלּוּ לַעֲשׂוֹת, וְאֵת אֲשֶׁר כָּתַב מָרְדֳּכַי אֲלֵיהֶם: כִּי הָמָן בֶּן הַמְּדָתָא הָאֲגָגִי צֹרֵר כָּל הַיְּהוּדִים חָשַׁב עַל הַיְּהוּדִים לְאַבְּדָם, וְהִפִּיל פּוּר הוּא הַגּוֹרָל לְהֻמָּם וּלְאַבְּדָם: וּבְבֹאָהּ לִפְנֵי הַמֶּלֶךְ, אָמַר עִם הַסֵּפֶר יָשׁוּב מַחֲשַׁבְתּוֹ הָרָעָה אֲשֶׁר חָשַׁב עַל הַיְּהוּדִים עַל רֹאשׁוֹ, וְתָלוּ אֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ: עַל כֵּן קָרְאוּ לַיָּמִים הָאֵלֶּה פוּרִים עַל שֵׁם הַפּוּר, עַל כֵּן עַל כָּל דִּבְרֵי הָאִגֶּרֶת הַזֹּאת, וּמָה רָאוּ עַל כָּכָה וּמָה הִגִּיעַ אֲלֵיהֶם: קִיְּמוּ וְקִבְּלוּ הַיְּהוּדִים עֲלֵיהֶם וְעַל זַרְעָם וְעַל כָּל הַנִּלְוִים עֲלֵיהֶם וְלֹא יַעֲבוֹר, לִהְיוֹת עֹשִׂים אֵת שְׁנֵי הַיָּמִים הָאֵלֶּה כִּכְתָבָם וְכִזְמַנָּם, בְּכָל שָׁנָה וְשָׁנָה: וְהַיָּמִים הָאֵלֶּה נִזְכָּרִים וְנַעֲשִׂים בְּכָל דּוֹר וָדוֹר מִשְׁפָּחָה וּמִשְׁפָּחָה מְדִינָה וּמְדִינָה וְעִיר וָעִיר, וִימֵי הַפּוּרִים הָאֵלֶּה לֹא יַעַבְרוּ מִתּוֹךְ הַיְּהוּדִים וְזִכְרָם לֹא יָסוּף מִזַּרְעָם: וַתִּכְתֹּב אֶסְתֵּר הַמַּלְכָּה בַת אֲבִיחַיִל וּמָרְדֳּכַי הַיְּהוּדִי אֶת כָּל תֹּקֶף, לְקַיֵּם אֵת אִגֶּרֶת הַפּוּרִים הַזֹּאת הַשֵּׁנִית: וַיִּשְׁלַח סְפָרִים אֶל כָּל הַיְּהוּדִים, אֶל שֶׁבַע וְעֶשְׂרִים וּמֵאָה מְדִינָה מַלְכוּת אֲחַשְׁוֵרוֹשׁ, דִּבְרֵי שָׁלוֹם וֶאֱמֶת: לְקַיֵּם אֵת יְמֵי הַפֻּרִים הָאֵלֶּה בִּזְמַנֵּיהֶם כַּאֲשֶׁר קִיַּם עֲלֵיהֶם מָרְדֳּכַי הַיְּהוּדִי וְאֶסְתֵּר הַמַּלְכָּה וְכַאֲשֶׁר קִיְּמוּ עַל נַפְשָׁם וְעַל זַרְעָם, דִּבְרֵי הַצֹּמוֹת וְזַעֲקָתָם: וּמַאֲמַר אֶסְתֵּר קִיַּם דִּבְרֵי הַפֻּרִים הָאֵלֶּה, וְנִכְתָּב בַּסֵּפֶר:","cond":["megilatEster"]},{"kind":"header","text":"פרק י'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק י'","cond":["megilatEster"]},{"kind":"text","text":"וַיָּשֶׂם הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ מַס עַל הָאָרֶץ וְאִיֵּי הַיָּם: וְכָל מַעֲשֵׂה תָקְפּוֹ וּגְבוּרָתוֹ, וּפָרָשַׁת גְּדֻלַּת מָרְדֳּכַי אֲשֶׁר גִּדְּלוֹ הַמֶּלֶךְ, הֲלוֹא הֵם כְּתוּבִים עַל סֵפֶר דִּבְרֵי הַיָּמִים לְמַלְכֵי מָדַי וּפָרָס:","cond":["megilatEster"]},{"kind":"special","text":"כִּי מָרְדֳּכַי הַיְּהוּדִי מִשְׁנֶה לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ וְגָדוֹל לַיְּהוּדִים וְרָצוּי לְרֹב אֶחָיו, דֹּרֵשׁ טוֹב לְעַמּוֹ וְדֹבֵר שָׁלוֹם לְכָל זַרְעוֹ:","cond":["megilatEster"]},{"kind":"header","text":"ברכת הרב את ריבנו","cond":["megilatEster"]},{"kind":"instruction","text":"ברכת הרב את ריבנו מברכים גם ביום וגם בלילה, ומברכים אותה רק בציבור של עשרה. ברכה זו מברך רק החזן הקורא את המגילה לאחר שכרך את כל המגילה.","cond":["megilatEster"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הָרָב אֶת רִיבֵנוּ, וְהַדָּן אֶת דִּינֵנוּ, וְהַנּוֹקֵם אֶת נִקְמָתֵנוּ, וְהַמְשַׁלֵּם גְּמוּל לְכָל אוֹיְבֵי נַפְשֵׁנוּ, וְהַנִּפְרָע לָנוּ מִצָּרֵינוּ. בָּרוּךְ אַתָּה יהוה, הַנִּפְרָע לְעַמּוֹ יִשְׂרָאֵל מִכָּל צָרֵיהֶם, הָאֵל הַמּוֹשִׁיעַ.","cond":["megilatEster"]},{"kind":"header","text":"אשר הניא","cond":["megilatEster"]},{"kind":"instruction","text":"אשר הניא\n\nבשחרית מתחילים משושנת יעקב. ויש נוהגים לומר \"אשר הניא\" אף בשחרית, אם אין אומרים פיוטים בחזרת הש\"ץ.","cond":["megilatEster"]},{"kind":"text","text":"אֲשֶׁר הֵנִיא עֲצַת גּוֹיִם, וַיָּפֶר מַחְשְׁבוֹת עֲרוּמִים.\nבְּקוּם עָלֵינוּ אָדָם רָשָׁע, נֵצֶר זָדוֹן מִזֶּרַע עֲמָלֵק.\nגָּאָה בְעָשְׁרוֹ וְכָרָה לוֹ בּוֹר, וּגְדֻלָּתוֹ יָקְשָׁה לּוֹ לָכֶד.\nדִּמָּה בְנַפְשׁוֹ לִלְכֹּד וְנִלְכַּד, בִּקֵּשׁ לְהַשְׁמִיד וְנִשְׁמַד מְהֵרָה.\nהָמָן הוֹדִיעַ אֵיבַת אֲבוֹתָיו, וְעוֹרֵר שִׂנְאַת אַחִים לַבָּנִים.\nוְלֹא זָכַר רַחֲמֵי שָׁאוּל, כִּי בְחֶמְלָתוֹ עַל אֲגָג נוֹלַד אוֹיֵב.\nזָמַם רָשָׁע לְהַכְרִית צַדִּיק, וְנִלְכַּד טָמֵא בִּידֵי טָהוֹר.\nחֶסֶד גָּבַר עַל שִׁגְגַת אָב, וְרָשָׁע הוֹסִיף חֵטְא עַל חֲטָאָיו.\nטָמַן בְּלִבּוֹ מַחְשְׁבוֹת עֲרוּמָיו, וַיִּתְמַכֵּר לַעֲשׂוֹת רָעָה.\nיָדוֹ שָׁלַח בִּקְדוֹשֵׁי אֵל, כַּסְפּוֹ נָתַן לְהַכְרִית זִכְרָם.\nכִּרְאוֹת מָרְדֳּכַי כִּי יָצָא קֶצֶף, וְדָתֵי הָמָן נִתְּנוּ בְשׁוּשָׁן.\nלָבַשׁ שַׂק וְקָשַׁר מִסְפֵּד, וְגָזַר צוֹם וַיֵּשֶׁב עַל הָאֵפֶר.\nמִי זֶה יַעֲמֹד לְכַפֵּר שְׁגָגָה, וְלִמְחֹל חַטַּאת עֲוׂן אֲבוֹתֵינוּ.\nנֵץ פָּרַח מִלּוּלָב, הֵן הֲדַסָּה עָמְדָה לְעוֹרֵר יְשֵׁנִים.\nסָרִיסֶיהָ הִבְהִילוּ לְהָמָן, לְהַשְׁקוֹתוֹ יֵין חֲמַת תַּנִּינִים.\nעָמַד בְּעָשְׁרוֹ וְנָפַל בְּרִשְׁעוֹ, עָשָׂה לוֹ עֵץ וְנִתְלָה עָלָיו.\nפִּיהֶם פָּתְחוּ כָָּל יוֹשְׁבֵי תֵבֵל, כִּי פוּר הָמָן נֶהְפַּךְ לְפוּרֵנוּ.\nצַדִּיק נֶחֱלַץ מִיַּד רָשָׁע, אוֹיֵב נִתַּן תַּחַת נַפְשׁוֹ.\nקִיְּמוּ עֲלֵיהֶם לַעֲשׂוֹת פּוּרִים, וְלִשְׂמֹחַ בְּכָל שָׁנָה וְשָׁנָה.\nרָאִיתָ אֶת תְּפִלַּת מָרְדֳּכַי וְאֶסְתֵּר, הָמָן וּבָנָיו עַל הָעֵץ תָּלִיתָ.","cond":["megilatEster"]},{"kind":"header","text":"שושנת יעקב","cond":["megilatEster"]},{"kind":"text","text":"שׁוֹשַׁנַּת יַעֲקֹב צָהֲלָה וְשָׂמֵחָה, בִּרְאוֹתָם יַחַד תְּכֵלֶת מָרְדֳּכָי.\nתְּשׁוּעָתָם הָיִיתָ לָנֶצַח, וְתִקְוָתָם בְּכָל דּוֹר וָדוֹר.\nלְהוֹדִיעַ שֶׁכָּל קֹוֶיךָ לֹא יֵבֹשׁוּ, וְלֹא יִכָּלְמוּ לָנֶצַח כָּל הַחוֹסִים בָּךְ.\nאָרוּר הָמָן אֲשֶׁר בִּקֵשׁ לְאַבְּדִי. בָּרוּךְ מָרְדֳּכַי הַיְּהוּדִי.\nאֲרוּרָה זֶרֶשׁ אֵשֶׁת מַפְחִידִי. בְּרוּכָה אֶסְתֵּר [מְגִנָּה] בַּעֲדִי.\nאֲרוּרִים כָּל הָרְשָׁעִים. בְּרוּכִים כָּל הַצַּדִּיקִים.\nוְגַם חַרְבוֹנָה זָכוּר לַטּוֹב.","cond":["megilatEster"]},{"kind":"header","text":"ואתה קדוש","cond":["megilatEster"]},{"kind":"text","text":"וְאַתָּה קָדוֹשׁ יוֹשֵׁב תְּהִלּוֹת יִשְׂרָאֵל: וְקָרָא זֶה אֶל זֶה וְאָמַר: קָדוֹשׁ, קָדוֹשׁ, קָדוֹשׁ יהוה צְבָאוֹת, מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ: וּמְקַבְּלִין דֵּין מִן דֵּין וְאָמְרִין: קַדִּישׁ בִּשְׁמֵי מֵרוֹמַא עִלָאַה בֵּית שְׁכִינְתֵּהּ, קַדִּישׁ עַל אַרְעָא עוֹבַד גְּבוּרְתֵּהּ, קַדִּישׁ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא, יהוה צְבָאוֹת מַלְיָא כָל אַרְעָא זִיו יְקָרֵהּ. וַתִּשָּׂאֵנִי רוּחַ, וָאֶשְׁמַע אַחֲרַי קוֹל רַעַשׁ גָּדוֹל: בָּרוּךְ כְּבוֹד יהוה מִמְּקוֹמוֹ: וּנְטָלַתְנִי רוּחָא, וּשְׁמָעִית בַּתְרַי קַל זִיעַ שַׂגִּיא דִמְשַׁבְּחִין וְאָמְרִין: בְּרִיךְ יְקָרָא דַיהוה מֵאֲתָר בֵּית שְׁכִינְתֵּהּ. יהוה יִמְלֹךְ לְעוֹלָם וָעֶד: יהוה מַלְכוּתֵיהּ קָאֵים לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\n\nיהוה אֱלֹהֵי אַבְרָהָם יִצְחָק וְיִשְׂרָאֵל אֲבוֹתֵינוּ, שָׁמְרָה זֹּאת לְעוֹלָם, לְיֵצֶר מַחְשְׁבוֹת לְבַב עַמֶּךָ, וְהָכֵן לְבָבָם אֵלֶיךָ: וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית, וְהִרְבָּה לְהָשִׁיב אַפּוֹ, וְלֹא יָעִיר כָּל חֲמָתוֹ: כִּי אַתָּה יהוה טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קוֹרְאֶיךָ: צִדְקָתְךָ צֶּדֶק לְעוֹלָם, וְתוֹרָתְךָ אֱמֶת: תִּתֵּן אֱמֶת לְיַעֲקֹב, חֶסֶד לְאַבְרָהָם, אֲשֶׁר נִשְׁבַּעְתָּ לַאֲבֹתֵינוּ מִימֵי קֶדֶם: בָּרוּךְ אֲדֹנָי יוֹם יוֹם, יַעֲמָס לָנוּ הָאֵל יְשׁוּעָתֵנוּ, סֶלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב, סֶלָה: יהוה צְבָאוֹת אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ: בָּרוּךְ הוּא אֱלֹהֵינוּ שֶׁבְּרָאָנוּ לִכְבוֹדוֹ, וְהִבְדִּילָנוּ מִן הַתּוֹעִים, וְנָתַן לָנוּ תּוֹרַת אֱמֶת, וְחַיֵּי עוֹלָם נָטַע בְּתוֹכֵנוּ. הוּא יִפְתַּח לִבֵּנוּ בְּתוֹרָתוֹ, וְיָשֵׂם בְּלִבֵּנוּ אַהֲבָתוֹ וְיִרְאָתוֹ וְלַעֲשׂוֹת רְצוֹנוֹ וּלְעָבְדוֹ בְּלֵבָב שָׁלֵם. לְמַעַן לֹא נִיגַע לָרִיק, וְלֹא נֵלֵד לַבֶּהָלָה. יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁנִּשְׁמֹר חֻקֶּיךָ בָּעוֹלָם הַזֶּה, וְנִזְכֶּה וְנִחְיֶה וְנִרְאֶה וְנִירַשׁ טוֹבָה וּבְרָכָה לִשְׁנֵי יְמוֹת הַמָּשִׁיחַ וּלְחַיֵּי הָעוֹלָם הַבָּא. לְמַעַן יְזַמֶּרְךָ כָבוֹד וְלֹא יִדֹּם, יהוה אֱלֹהַי לְעוֹלָם אוֹדֶךָּ: בָּרוּךְ הַגֶּבֶר אֲשֶׁר יִבְטַח בַּיהוה, וְהָיָה יהוה מִבְטַחוֹ: בִּטְחוּ בַיהוה עֲדֵי עַד, כִּי בְּיָהּ יהוה צוּר עוֹלָמִים: וְיִבְטְחוּ בְךָ יוֹדְעֵי שְׁמֶךָ, כִּי לֹא עָזַבְתָּ דֹּרְשֶׁיךָ יהוה: יהוה חָפֵץ לְמַעַן צִדְקוֹ, יַגְדִּיל תּורָה וְיַאְדִּיר:","cond":["megilatEster"]},{"kind":"instruction","text":"מברך לאור הנר:","cond":["tishaaBeavFire"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא מְאוֹרֵי הָאֵשׁ.","cond":["tishaaBeavFire"]},{"kind":"header","text":"ואתה קדוש","cond":["tishaaBeav"]},{"kind":"text","text":"וְאַתָּה קָדוֹשׁ יוֹשֵׁב תְּהִלּוֹת יִשְׂרָאֵל: וְקָרָא זֶה אֶל זֶה וְאָמַר: קָדוֹשׁ, קָדוֹשׁ, קָדוֹשׁ יהוה צְבָאוֹת, מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ: וּמְקַבְּלִין דֵּין מִן דֵּין וְאָמְרִין: קַדִּישׁ בִּשְׁמֵי מֵרוֹמַא עִלָאַה בֵּית שְׁכִינְתֵּהּ, קַדִּישׁ עַל אַרְעָא עוֹבַד גְּבוּרְתֵּהּ, קַדִּישׁ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא, יהוה צְבָאוֹת מַלְיָא כָל אַרְעָא זִיו יְקָרֵהּ. וַתִּשָּׂאֵנִי רוּחַ, וָאֶשְׁמַע אַחֲרַי קוֹל רַעַשׁ גָּדוֹל: בָּרוּךְ כְּבוֹד יהוה מִמְּקוֹמוֹ: וּנְטָלַתְנִי רוּחָא, וּשְׁמָעִית בַּתְרַי קַל זִיעַ שַׂגִּיא דִמְשַׁבְּחִין וְאָמְרִין: בְּרִיךְ יְקָרָא דַיהוה מֵאֲתָר בֵּית שְׁכִינְתֵּהּ. יהוה יִמְלֹךְ לְעוֹלָם וָעֶד: יהוה מַלְכוּתֵיהּ קָאֵים לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\n\nיהוה אֱלֹהֵי אַבְרָהָם יִצְחָק וְיִשְׂרָאֵל אֲבוֹתֵינוּ, שָׁמְרָה זֹּאת לְעוֹלָם, לְיֵצֶר מַחְשְׁבוֹת לְבַב עַמֶּךָ, וְהָכֵן לְבָבָם אֵלֶיךָ: וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית, וְהִרְבָּה לְהָשִׁיב אַפּוֹ, וְלֹא יָעִיר כָּל חֲמָתוֹ: כִּי אַתָּה יהוה טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קוֹרְאֶיךָ: צִדְקָתְךָ צֶּדֶק לְעוֹלָם, וְתוֹרָתְךָ אֱמֶת: תִּתֵּן אֱמֶת לְיַעֲקֹב, חֶסֶד לְאַבְרָהָם, אֲשֶׁר נִשְׁבַּעְתָּ לַאֲבֹתֵינוּ מִימֵי קֶדֶם: בָּרוּךְ אֲדֹנָי יוֹם יוֹם, יַעֲמָס לָנוּ הָאֵל יְשׁוּעָתֵנוּ, סֶלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב, סֶלָה: יהוה צְבָאוֹת אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ: בָּרוּךְ הוּא אֱלֹהֵינוּ שֶׁבְּרָאָנוּ לִכְבוֹדוֹ, וְהִבְדִּילָנוּ מִן הַתּוֹעִים, וְנָתַן לָנוּ תּוֹרַת אֱמֶת, וְחַיֵּי עוֹלָם נָטַע בְּתוֹכֵנוּ. הוּא יִפְתַּח לִבֵּנוּ בְּתוֹרָתוֹ, וְיָשֵׂם בְּלִבֵּנוּ אַהֲבָתוֹ וְיִרְאָתוֹ וְלַעֲשׂוֹת רְצוֹנוֹ וּלְעָבְדוֹ בְּלֵבָב שָׁלֵם. לְמַעַן לֹא נִיגַע לָרִיק, וְלֹא נֵלֵד לַבֶּהָלָה. יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁנִּשְׁמֹר חֻקֶּיךָ בָּעוֹלָם הַזֶּה, וְנִזְכֶּה וְנִחְיֶה וְנִרְאֶה וְנִירַשׁ טוֹבָה וּבְרָכָה לִשְׁנֵי יְמוֹת הַמָּשִׁיחַ וּלְחַיֵּי הָעוֹלָם הַבָּא. לְמַעַן יְזַמֶּרְךָ כָבוֹד וְלֹא יִדֹּם, יהוה אֱלֹהַי לְעוֹלָם אוֹדֶךָּ: בָּרוּךְ הַגֶּבֶר אֲשֶׁר יִבְטַח בַּיהוה, וְהָיָה יהוה מִבְטַחוֹ: בִּטְחוּ בַיהוה עֲדֵי עַד, כִּי בְּיָהּ יהוה צוּר עוֹלָמִים: וְיִבְטְחוּ בְךָ יוֹדְעֵי שְׁמֶךָ, כִּי לֹא עָזַבְתָּ דֹּרְשֶׁיךָ יהוה: יהוה חָפֵץ לְמַעַן צִדְקוֹ, יַגְדִּיל תּורָה וְיַאְדִּיר:","cond":["tishaaBeav"]},{"kind":"instruction","text":"קדיש שלם (ללא תתקבל)","cond":["megilatEster"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":["megilatEster"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["megilatEster","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["megilatEster","ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["megilatEster"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["megilatEster","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["megilatEster","ayt"]},{"kind":"instruction","text":"קדיש שלם (ללא תתקבל)","cond":["tishaaBeav"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":["tishaaBeav"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","ayt"]},{"kind":"header","text":"ויתן לך","cond":["sun"]},{"kind":"instruction","text":"פסוקים הנהוגים לומר במוצאי שבת לסימן ברכה:","cond":["sun"]},{"kind":"text","text":"וְיִתֶּן לְךָ הָאֱלהִים מִטַּל הַשָּׁמַיִם וּמִשְׁמַנֵּי הָאָרֶץ, וְרֹב דָגָן וְתִירֹשׁ: יַעַבְדּוּךָ עַמִּים וְיִשְׁתַּחֲווּ לְךָ לְאֻמִּים, הֱוֵה גְבִיר לְאַחֶיךָ וְיִשְׁתַּחֲווּ לְךָ בְּנֵי אִמֶּךָ, אֹרְרֶיךָ אָרוּר וּמְבָרְכֶיךָ בָּרוּךְ:\n\nוְאֵל שַׁדַּי יְבָרֵךְ אֹתְךָ וְיַפְרְךָ וְיַרְבֶּךָ, וְהָיִיתָ לִקְהַל עַמִּים: וְיִתֵּן לְךָ אֶת בִּרְכַּת אַבְרָהָם לְךָ וּלְזַרְעֲךָ אִתָּךְ, לְרִשְׁתְּךָ אֶת אֶרֶץ מְגֻרֶיךָ, אֲשֶׁר נָתַן אֱלֹהִים לְאַבְרָהָם: מֵאֵל אָבִיךָ וְיַעְזְרֶךָּ, וְאֵת שַׁדַּי וִיבָרְכֶךָּ, בִּרְכֹת שָׁמַיִם מֵעָל, בִּרְכֹת תְּהוֹם רֹבֶצֶת תָּחַת, בִּרְכֹת שָׁדַיִם וָרָחַם: בִּרְכֹת אָבִיךָ גָּבְרוּ עַל בִּרְכֹת הוֹרַי עַד תַּאֲוַת גִּבְעֹת עוֹלָם, תִּהְיֶיןָ לְרֹאשׁ יוסֵף וּלְקָדְקֹד נְזִיר אֶחָיו: וַאֲהֵבְךָ וּבֵרַכְךָ וְהִרְבֶּךָ, וּבֵרַךְ פְּרִי בִטְנְךָ וּפְרִי אַדְמָתֶךָ, דְּגָנְךָ וְתִירֹשְׁךָ וְיִצְהָרֶךָ, שְׁגַר אֲלָפֶיךָ וְעַשְׁתְּרֹת צֹאנֶךָ, עַל הָאֲדָמָה אֲשֶׁר נִשְׁבַּע לַאֲבֹתֶיךָ לָתֶת לָךְ: בָּרוּךְ תִּהְיֶה מִכָּל הָעַמִּים, לֹא יִהְיֶה בְךָ עָקָר וַעֲקָרָה וּבִבְהֶמְתֶּךָ: וְהֵסִיר יהוה מִמְּךָ כָּל חֹלִי, וְכָל מַדְוֵי מִצְרַיִם הָרָעִים אֲשֶׁר יָדַעְתָּ לֹא יְשִׂימָם בָּךְ, וּנְתָנָם בְּכָל שֹׂנְאֶיךָ:\n\nהַמַּלְאָךְ הַגֹּאֵל אֹתִי מִכָּל רָע יְבָרֵךְ אֶת הַנְּעָרִים, וְיִקָּרֵא בָהֶם שְׁמִי, וְשֵׁם אֲבֹתַי אַבְרָהָם וְיִצְחָק, וְיִדְגּוּ לָרֹב בְּקֶרֶב הָאָרֶץ: יהוה אֱלֹהֵיכֶם הִרְבָּה אֶתְכֶם, וְהִנְּכֶם הַיּוֹם כְּכוֹכְבֵי הַשָּׁמַיִם לָרֹב: יהוה אֱלֹהֵי אֲבוֹתֵכֶם יֹסֵף עֲלֵיכֶם כָּכֶם אֶלֶף פְּעָמִים, וִיבָרֵךְ אֶתְכֶם כַּאֲשֶׁר דִּבֶּר לָכֶם:\n\nבָּרוּךְ אַתָּה בָּעִיר, וּבָרוּךְ אַתָּה בַּשָּׂדֶה: בָּרוּךְ אַתָּה בְּבֹאֶךָ, וּבָרוּךְ אַתָּה בְּצֵאתֶךָ: בָּרוּךְ טַנְאֲךָ וּמִשְׁאַרְתֶּךָ: בָּרוּךְ פְּרִי בִטְנְךָ וּפְרִי אַדְמָתְךָ וּפְרִי בְהֶמְתֶּךָ, שְׁגַר אֲלָפֶיךָ וְעַשְׁתְּרוֹת צֹאנֶךָ: יְצַו יהוה אִתְּךָ אֶת הַבְּרָכָה, בַּאֲסָמֶיךָ וּבְכֹל מִשְׁלַח יָדֶךָ, וּבֵרַכְךָ בָּאָרֶץ אֲשֶׁר יהוה אֱלהֶיךָ נֹתֵן לָךְ: יִפְתַּח יהוה לְךָ אֶת אוֹצָרוֹ הַטּוֹב אֶת הַשָּׁמַיִם לָתֵת מְטַר אַרְצְךָ בְּעִתּוֹ וּלְבָרֵךְ אֵת כָּל מַעֲשֵׂה יָדֶךָ, וְהִלְוִיתָ גּוֹיִם רַבִּים וְאַתָּה לֹא תִלְוֶה: כִּי יהוה אֱלֹהֶיךָ בֵּרַכְךָ כַּאֲשֶׁר דִּבֶּר לָךְ, וְהַעֲבַטְתָּ גּוֹיִם רַבִּים וְאַתָּה לֹא תַעֲבֹט, וּמָשַׁלְתָּ בְּגוֹיִם רַבִּים וּבְךָ לֹא יִמְשֹׁלוּ: אַשְׁרֶיךָ יִשְׂרָאֵל, מִי כָמוֹךָ, עַם נושַׁע בַּיהוה, מָגֵן עֶזְרֶךָ, וַאֲשֶׁר חֶרֶב גַּאֲוָתֶךָ, וְיִכָּחֲשׁוּ אוֹיְבֶיךָ לָךְ, וְאַתָּה עַל בָּמוֹתֵימוֹ תִדְרֹךְ:\n\nמָחִיתִי כָעָב פְּשָׁעֶיךָ וְכֶעָנָן חַטֹּאותֶיךָ, שׁוּבָה אֵלַי כִּי גְאַלְתִּיךָ: רָנּוּ שָׁמַיִם כִּי עָשָׂה יהוה, הָרִיעוּ תַּחְתִּיּוֹת אָרֶץ, פִּצְחוּ הָרִים רִנָּה, יַעַר וְכָל עֵץ בּוֹ, כִּי גָאַל יהוה יַעֲקֹב וּבְיִשְׂרָאֵל יִתְפָּאָר: גֹּאֲלֵנוּ יהוה צְבָאוֹת שְׁמוֹ, קְדוֹשׁ יִשְׂרָאֵל:\n\nיִשְׂרָאֵל נוֹשַׁע בַּיהוה תְּשׁוּעַת עוֹלָמִים, לֹא תֵבשׁוּ וְלֹא תִכָּלְמוּ עַד עוֹלְמֵי עַד: וַאֲכַלְתֶּם אָכוֹל וְשָׂבוֹעַ, וְהִלַּלְתֶּם אֶת שֵׁם יהוה אֱלֹהֵיכֶם אֲשֶׁר עָשָׂה עִמָּכֶם לְהַפְלִיא, וְלֹא יֵבֹשׁוּ עַמִּי לְעוֹלָם: וִידַעְתֶּם כִּי בְקֶרֶב יִשְׂרָאֵל אָנִי, וַאֲנִי יהוה אֱלֹהֵיכֶם וְאֵין עוֹד, וְלֹא יֵבשׁוּ עַמִּי לְעוֹלָם: כִּי בְשִׂמְחָה תֵצֵאוּ וּבְשָׁלוֹם תּוּבָלוּן, הֶהָרִים וְהַגְּבָעוֹת יִפְצְחוּ לִפְנֵיכֶם רִנָּה, וְכָל עֲצֵי הַשָּׂדֶה יִמְחֲאוּ כָף: הִנֵּה אֵל יְשׁוּעָתִי אֶבְטַח, וְלֹא אֶפְחָד, כִּי עָזִּי וְזִמְרָת יָהּ יהוה, וַיְהִי לִי לִישׁוּעָה: וּשְׁאַבְתֶּם מַיִם בְּשָׂשׂוֹן מִמַּעַיְנֵי הַיְשׁוּעָה: וַאֲמַרְתֶּם בַּיּוֹם הַהוּא, הוֹדוּ לַיהוה קִרְאוּ בִשְׁמוֹ, הוֹדִיעוּ בָעַמִּים עֲלִילֹתָיו, הַזְכִּירוּ כִּי נִשְׂגָּב שְׁמוֹ: זַמְּרוּ יהוה כִּי גֵאוּת עָשָׂה, מוּדַעַת זֹאת בְּכָל הָאָרֶץ: צַהֲלִי וָרֹנִּי יוֹשֶׁבֶת צִיּוֹן, כִּי גָדוֹל בְּקִרְבֵּךְ קְדוֹשׁ יִשְׂרָאֵל: וְאָמַר בַּיּוֹם הַהוּא, הִנֵּה אֱלֹהֵינוּ זֶה קִוִּינוּ לוֹ, וְיוֹשִׁיעֵנוּ, זֶה יהוה קִוִּינוּ לוֹ, נָגִילָה וְנִשְׂמְחָה בִּישׁוּעָתוֹ: בֵּית יַעֲקֹב, לְכוּ וְנֵלְכָה בְּאוֹר יהוה: וְהָיָה אֱמוּנַת עִתֶּיךָ, חֹסֶן יְשׁוּעֹת, חָכְמַת וָדָעַת, יִרְאַת יהוה הִיא אוֹצָרוֹ: וַיְהִי דָוִד לְכָל דְּרָכָיו מַשְׂכִּיל, וַיהוה עִמּוֹ:\n\nפָּדָה בְשָׁלוֹם נַפְשִׁי מִקְּרָב לִי, כִּי בְרַבִּים הָיוּ עִמָּדִי: וַיֹּאמֶר הָעָם אֶל שָׁאוּל, הֲיוֹנָתָן יָמוּת, אֲשֶׁר עָשָׂה הַיְשׁוּעָה הַגְּדוֹלָה הַזֹּאת בְּיִשְׂרָאֵל, חָלִילָה, חַי יהוה אִם יִפֹּל מִשַּׂעֲרַת רֹאשׁוֹ אַרְצָה, כִּי עִם אֱלֹהִים עָשָׂה הַיּוֹם הַזֶּה, וַיִּפְדּוּ הָעָם אֶת יוֹנָתָן וְלֹא מֵת: וּפְדוּיֵי יהוה יְשֻׁבוּן וּבָאוּ צִיּוֹן בְּרִנָּה וְשִׂמְחַת עוֹלָם עַל רֹאשָׁם, שָׂשׂוֹן וְשִׂמְחָה יַשִּׂיגוּ, וְנָסוּ יָגוֹן וַאֲנָחָה:\n\nהָפַכְתָּ מִסְפְּדִי לְמָחוֹל לִי, פִּתַּחְתָּ שַׂקִּי וַתְּאַזְּרֵנִי שִׂמְחָה: וְלֹא אָבָה יהוה אֱלֹהֶיךָ לִשְׁמֹעַ אֶל בִּלְעָם, וַיַּהֲפֹךְ יהוה אֱלֹהֶיךָ לְּךָ אֶת הַקְּלָלָה לִבְרָכָה, כִּי אֲהֵבְךָ יהוה אֱלֹהֶיךָ: אָז תִּשְׂמַח בְּתוּלָה בְּמָחוֹל וּבַחֻרִים וּזְקֵנִים יַחְדָּו, וְהָפַכְתִּי אֶבְלָם לְשָׂשׂוֹן וְנִחַמְתִּים, וְשִׂמַּחְתִּים מִיגוֹנָם:\n\nבּוֹרֵא נִיב שְׂפָתָיִם, שָׁלוֹם שָׁלוֹם לָרָחוֹק וְלַקָּרוֹב אָמַר יהוה, וּרְפָאתִיו: וְרוּחַ לָבְשָׁה אֶת עֲמָשַׂי רֹאשׁ הַשָּׁלִישִׁים, לְךָ דָוִיד וְעִמְּךָ בֶן יִשַׁי שָׁלוֹם, שָׁלוֹם לְךָ וְשָׁלוֹם לְעֹזְרֶךָ כִּי עֲזָרְךָ אֱלֹהֶיךָ, וַיְקַבְּלֵם דָּוִיד וַיִּתְּנֵם בְּרָאשֵׁי הַגְּדוּד: וַאֲמַרְתֶּם כֹּה לֶחָי, וְאַתָּה שָׁלוֹם, וּבֵיתְךָ שָׁלוֹם וְכֹל אֲשֶׁר לְךָ שָׁלוֹם: יהוה עֹז לְעַמּוֹ יִתֵּן, יהוה יְבָרֵךְ אֶת עַמּוֹ בַשָּׁלוֹם:\n\nאָמַר רַבִּי יוֹחָנָן: בְּכָל מָקוֹם שֶׁאַתָּה מוֹצֵא גְּדֻלָּתוֹ שֶׁל הַקָּדוֹשׁ בָּרוּךְ הוּא, שָׁם אַתָּה מוֹצֵא עַנְוְתָנוּתוֹ. דָּבָר זֶה כָּתוּב בַּתּוֹרָה, וְשָׁנוּי בַּנְּבִיאִים, וּמְשֻׁלָּשׁ בַּכְּתוּבִים. כָּתוּב בַּתּוֹרָה: כִּי יהוה אֱלֹהֵיכֶם הוּא אֱלֹהֵי הָאֱלֹהִים וַאֲדֹנֵי הָאֲדֹנִים, הָאֵל הַגָּדֹל, הַגִּבֹּר וְהַנּוֹרָא, אֲשֶׁר לֹא יִשָּׂא פָנִים וְלֹא יִקַּח שֹׁחַד: וּכְתִיב בָּתְרֵיהּ: עֹשֶׂה מִשְׁפַּט יָתוֹם וְאַלְמָנָה, וְאֹהֵב גֵּר לָתֶת לוֹ לֶחֶם וְשִׂמְלָה: שָׁנוּי בַּנְּבִיאִים, דִּכְתִיב: כִּי כֹה אָמַר רָם וְנִשָּׂא, שֹׁכֵן עַד וְקָדוֹשׁ שְׁמוֹ, מָרוֹם וְקָדוֹשׁ אֶשְׁכּוֹן, וְאֶת דַּכָּא וּשְׁפַל רוּחַ, לְהַחֲיוֹת רוּחַ שְׁפָלִים וּלְהַחֲיוֹת לֵב נִדְכָּאִים: מְשֻׁלָּשׁ בַּכְּתוּבִים, דִּכְתִיב: שִׁירוּ לֵאלֹהִים זַמְּרוּ שְׁמוֹ, סֹלּוּ לָרֹכֵב בָּעֲרָבוֹת בְּיָהּ שְׁמוֹ, וְעִלְזוּ לְפָנָיו: וּכְתִיב בָּתְרֵיהּ: אֲבִי יְתוֹמִים וְדַיַּן אַלְמָנוֹת, אֱלֹהִים בִּמְעוֹן קָדְשׁוֹ:\n\nיְהִי יהוה אֱלֹהֵינוּ עִמָּנוּ כַּאֲשֶׁר הָיָה עִם אֲבֹתֵינוּ, אַל יַעַזְבֵנוּ וְאַל יִטְּשֵׁנוּ: וְאַתֶּם הַדְּבֵקִים בַּיהוה אֱלֹהֵיכֶם, חַיִּים כֻּלְּכֶם הַיּוֹם: כִּי נִחַם יהוה צִיּוֹן, נִחַם כָּל חָרְבֹתֶיהָ, וַיָּשֶׂם מִדְבָּרָהּ כְּעֵדֶן וְעַרְבָתָהּ כְּגַן יהוה, שָׂשׂוֹן וְשִׂמְחָה יִמָּצֵא בָהּ, תּוֹדָה וְקוֹל זִמְרָה: יהוה חָפֵץ לְמַעַן צִדְקוֹ, יַגְדִּיל תּוֹרָה וְיַאְדִּיר:\n\nשִׁיר הַמַּעֲלוֹת, אַשְׁרֵי כָּל יְרֵא יהוה הַהֹלֵךְ בִּדְרָכָיו: יְגִיעַ כַּפֶּיךָ כִּי תֹאכֵל, אַשְׁרֶיךָ וְטוֹב לָךְ: אֶשְׁתְּךָ כְּגֶפֶן פֹּרִיָּה בְּיַרְכְּתֵי בֵיתֶךָ, בָּנֶיךָ כִּשְׁתִלֵי זֵיתִים סָבִיב לְשֻׁלְחָנֶךָ: הִנֵּה כִי כֵן יְבֹרַךְ גָּבֶר יְרֵא יהוה: יְבָרֶכְךָ יהוה מִצִּיּוֹן וּרְאֵה בְּטוּב יְרוּשָׁלָיִם, כֹּל יְמֵי חַיֶּיךָ: וּרְאֵה בָנִים לְבָנֶיךָ, שָׁלוֹם עַל יִשְׂרָאֵל:","cond":["sun"]},{"kind":"header","text":"עלינו לשבח","cond":[]},{"kind":"text","text":"עָלֵינוּ לְשַׁבֵּחַ לַאֲדוֹן הַכֹּל, לָתֵת גְּדֻלָּה לְיוֹצֵר בְּרֵאשִׁית, שֶׁלֹּא עָשָׂנוּ כְּגוֹיֵי הָאֲרָצוֹת, וְלֹא שָׂמָנוּ כְּמִשְׁפְּחוֹת הָאֲדָמָה. שֶׁלֹּא שָׂם חֶלְקֵנוּ כָּהֶם, וְגוֹרָלֵנוּ כְּכָל-הֲמוֹנָם, שֶׁהֵם מִשְׁתַּחֲוִים לְהֶבֶל וָרִיק, וּמִתְפַּלְּלִים אֶל אֵל לֹא יוֹשִׁיעַ. וַאֲנַחְנוּ כּוֹרְעִים וּמִשְׁתַּחֲוִים וּמוֹדִים לִפְנֵי מֶלֶךְ מַלְכֵי הַמְּלָכִים הַקָּדוֹשׁ בָּרוּךְ הוּא, שֶׁהוּא נוֹטֶה שָׁמַיִם וְיוֹסֵד אָרֶץ, וּמוֹשַׁב יְקָרוֹ בַּשָּׁמַיִם מִמַּעַל, וּשְׁכִינַת עֻזּוֹ בְּגָבְהֵי מְרוֹמִים. הוּא אֱלֹהֵינוּ, אֵין עוֹד, אֱמֶת מַלְכֵּנוּ, אֶפֶס זוּלָתוֹ, כַּכָּתוּב בְּתוֹרָתוֹ: וְיָדַעְתָּ הַיּוֹם וַהֲשֵׁבֹתָ אֶל לְבָבֶךָ כִּי יהוה הוּא הָאֱלֹהִים בַּשָּׁמַיִם מִמַּעַל וְעַל הָאָרֶץ מִתָּחַת אֵין עוֹד:","cond":[]},{"kind":"text","text":"עַל כֵּן נְקַוֶּה לְךָ יהוה אֱלֹהֵינוּ, לִרְאוֹת מְהֵרָה בְּתִפְאֶרֶת עֻזֶּךָ, לְהַעֲבִיר גִּלּוּלִים מִן הָאָרֶץ, וְהָאֱלִילִים כָּרוֹת יִכָּרֵתוּן, לְתַקֵּן עוֹלָם בְּמַלְכוּת שַׁדַּי, וְכָל בְּנֵי בָשָׂר יִקְרְאוּ בִשְׁמֶךָ, לְהַפְנוֹת אֵלֶיךָ כָּל רִשְׁעֵי אָרֶץ. יַכִּירוּ וְיֵדְעוּ כָּל יוֹשְׁבֵי תֵבֵל, כִּי לְךָ תִכְרַע כָּל בֶּרֶךְ, תִּשָּׁבַע כָּל לָשׁוֹן. לְפָנֶיךָ יהוה אֱלֹהֵינוּ יִכְרְעוּ וְיִפֹּלוּ, וְלִכְבוֹד שִׁמְךָ יְקָר יִתֵּנוּ, וִיקַבְּלוּ כֻלָּם אֶת עֹל מַלְכוּתֶךָ, וְתִמְלֹךְ עֲלֵיהֶם מְהֵרָה לְעוֹלָם וָעֶד. כִּי הַמַּלְכוּת שֶׁלְּךָ הִיא, וּלְעוֹלְמֵי עַד תִּמְלֹךְ בְּכָבוֹד, כַּכָּתוּב בְּתוֹרָתֶךָ: יהוה יִמְלֹךְ לְעֹלָם וָעֶד: וְנֶאֱמַר: וְהָיָה יהוה לְמֶלֶךְ עַל כָּל הָאָרֶץ בַּיּוֹם הַהוּא יִהְיֶה יהוה אֶחָד וּשְׁמוֹ אֶחָד:","cond":[]},{"kind":"text","text":"אַל תִּירָא מִפַּחַד פִּתְאֹם וּמִשֹּׁאַת רְשָׁעִים כִּי תָבֹא: עֻצוּ עֵצָה וְתֻפָר, דַּבְּרוּ דָבָר וְלֹא יָקוּם, כִּי עִמָּנוּ אֵל: וְעַד זִקְנָה אֲנִי הוּא, וְעַד שֵׂיבָה אֲנִי אֶסְבֹּל אֲנִי עָשִׂיתִי וַאֲנִי אֶשָּׂא וַאֲנִי אֶסְבֹּל וַאֲמַלֵּט:","cond":[]},{"kind":"instruction","text":"קדיש יתום","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":[]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"instruction","text":"חזן:","cond":[]},{"kind":"text","text":"בָּרְכוּ אֶת יהוה הַמְבֹרָךְ.","cond":[]},{"kind":"instruction","text":"קהל וחזן:","cond":[]},{"kind":"text","text":"בָּרוּךְ יהוה הַמְבֹרָךְ לְעוֹלָם וָעֶד.","cond":[]},{"kind":"header","text":"אני מאמין","cond":["yerushalayim"]},{"kind":"instruction","text":"שרים:","cond":["yerushalayim"]},{"kind":"text","text":"אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה בְּבִיאַת הַמָּשִׁיחַ, וְאַף עַל פִּי שֶׁיִּתְמַהְמֵהַּ, עִם כָּל זֶה אֲחַכֶּה לוֹ בְּכָל יוֹם שֶׁיָּבוֹא.","cond":["yerushalayim"]},{"kind":"header","text":"לדוד","cond":["ledavid"]},{"kind":"special","text":"לְדָוִד, יהוה אוֹרִי וְיִשְׁעִי מִמִּי אִירָא, יהוה מָעוֹז חַיַּי מִמִּי אֶפְחָד: בִּקְרֹב עָלַי מְרֵעִים לֶאֱכֹל אֶת בְּשָׂרִי, צָרַי וְאֹיְבַי לִי, הֵמָּה כָשְׁלוּ וְנָפָלוּ: אִם תַּחֲנֶה עָלַי מַחֲנֶה לֹא יִירָא לִבִּי, אִם תָּקוּם עָלַי מִלְחָמָה בְּזֹאת אֲנִי בוֹטֵחַ: אַחַת שָׁאַלְתִּי מֵאֵת יהוה, אוֹתָהּ אֲבַקֵּשׁ, שִׁבְתִּי בְּבֵית יהוה כָּל יְמֵי חַיַּי, לַחֲזוֹת בְּנֹעַם יהוה וּלְבַקֵּר בְּהֵיכָלוֹ: כִּי יִצְפְּנֵנִי בְּסֻכֹּה בְּיוֹם רָעָה יַסְתִּירֵנִי בְּסֵתֶר אָהֳלוֹ, בְּצוּר יְרוֹמְמֵנִי: וְעַתָּה יָרוּם רֹאשִׁי עַל אֹיְבַי סְבִיבוֹתַי, וְאֶזְבְּחָה בְאָהֳלוֹ זִבְחֵי תְרוּעָה, אָשִׁירָה וַאֲזַמְּרָה לַיהוה: שְׁמַע יהוה קוֹלִי אֶקְרָא, וְחָנֵּנִי וַעֲנֵנִי: לְךָ אָמַר לִבִּי בַּקְּשׁוּ פָנַי, אֶת פָּנֶיךָ יהוה אֲבַקֵּשׁ: אַל תַּסְתֵּר פָּנֶיךָ מִמֶּנִּי, אַל תַּט בְּאַף עַבְדֶּךָ, עֶזְרָתִי הָיִיתָ, אַל תִּטְּשֵׁנִי וְאַל תַּעַזְבֵנִי אֱלֹהֵי יִשְׁעִי: כִּי אָבִי וְאִמִּי עֲזָבוּנִי, וַיהוה יַאַסְפֵנִי: הוֹרֵנִי יהוה דַּרְכֶּךָ וּנְחֵנִי בְּאֹרַח מִישׁוֹר לְמַעַן שׁוֹרְרָי: אַל תִּתְּנֵנִי בְּנֶפֶשׁ צָרָי, כִּי קָמוּ בִי עֵדֵי שֶׁקֶר וִיפֵחַ חָמָס: לוּלֵא הֶאֱמַנְתִּי לִרְאוֹת בְּטוּב יהוה בְּאֶרֶץ חַיִּים: קַוֵּה אֶל יהוה, חֲזַק וְיַאֲמֵץ לִבֶּךָ, וְקַוֵּה אֶל יהוה:","cond":["ledavid"]},{"kind":"instruction","text":"קדיש יתום","cond":["ledavid"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":["ledavid"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ledavid","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ledavid","ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ledavid"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ledavid","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ledavid","ayt"]},{"kind":"header","text":"מזמור לבית האבל","cond":[]},{"kind":"instruction","text":"בבית האבל אומרים מזמור זה:","cond":["shacharitTachanun"]},{"kind":"text","text":"לַמְנַצֵּחַ לִבְנֵי קֹרַח מִזְמוֹר: שִׁמְעוּ זֹאת כָּל הָעַמִּים, הַאֲזִינוּ כָּל יֹשְׁבֵי חָלֶד: גַּם בְּנֵי אָדָם, גַּם בְּנֵי אִישׁ, יַחַד עָשִׁיר וְאֶבְיוֹן: פִּי יְדַבֵּר חָכְמוֹת, וְהָגוּת לִבִּי תְבוּנוֹת: אַטֶּה לְמָשָׁל אָזְנִי, אֶפְתַּח בְּכִנּוֹר חִידָתִי: לָמָּה אִירָא בִּימֵי רָע, עֲוׂן עֲקֵבַי יְסוּבֵּנִי: הַבֹּטְחִים עַל חֵילָם, וּבְרֹב עָשְׁרָם יִתְהַלָּלוּ: אָח לֹא פָדֹה יִפְדֶּה אִישׁ, לֹא יִתֵּן לֵאלֹהִים כָּפְרוֹ: וְיֵקַר פִּדְיוֹן נַפְשָׁם, וְחָדַל לְעוֹלָם: וִיחִי עוֹד לָנֶצַח, לֹא יִרְאֶה הַשָּׁחַת: כִּי יִרְאֶה חֲכָמִים יָמוּתוּ, יַחַד כְּסִיל וָבַעַר יֹאבֵדוּ, וְעָזְבוּ לַאֲחֵרִים חֵילָם: קִרְבָּם בָּתֵּימוֹ לְעוֹלָם, מִשְׁכְּנֹתָם לְדֹר וָדֹר, קָרְאוּ בִשְׁמוֹתָם עֲלֵי אֲדָמוֹת: וְאָדָם בִּיקָר בַּל יָלִין, נִמְשַׁל כַּבְּהֵמוֹת נִדְמוּ: זֶה דַרְכָּם כֵּסֶל לָמוֹ, וְאַחֲרֵיהֶם בְּפִיהֶם יִרְצוּ סֶלָה: כַּצֹּאן לִשְׁאוֹל שַׁתּוּ מָוֶת יִרְעֵם, וַיִּרְדּוּ בָם יְשָׁרִים לַבֹּקֶר, וְצוּרָם לְבַלּוֹת שְׁאוֹל מִזְּבֻל לוֹ: אַךְ אֱלֹהִים יִפְדֶּה נַפְשִׁי מִיַּד שְׁאוֹל, כִּי יִקָּחֵנִי סֶלָה: אַל תִּירָא כִּי יַעֲשִׁר אִישׁ, כִּי יִרְבֶּה כְּבוֹד בֵּיתוֹ: כִּי לֹא בְמוֹתוֹ יִקַּח הַכֹּל, לֹא יֵרֵד אַחֲרָיו כְּבוֹדוֹ: כִּי נַפְשׁוֹ בְּחַיָּיו יְבָרֵךְ, וְיוֹדֻךָ כִּי תֵיטִיב לָךְ: תָּבוֹא עַד דּוֹר אֲבוֹתָיו, עַד נֵצַח לֹא יִרְאוּ אוֹר: אָדָם בִּיקָר וְלֹא יָבִין נִמְשַׁל כַּבְּהֵמוֹת נִדְמוּ:","cond":["shacharitTachanun"]},{"kind":"instruction","text":"בבית האבל אומרים מזמור זה:","cond":["noShacharitTachanun"]},{"kind":"text","text":"מִכְתָּם לְדָוִד, שָׁמְרֵנִי אֵל כִּי חָסִיתִי בָךְ: אָמַרְתְּ לַיהוה, אֲדֹנָי אָתָּה, טוֹבָתִי בַּל עָלֶיךָ: לִקְדוֹשִׁים אֲשֶׁר בָּאָרֶץ הֵמָּה, וְאַדִּירֵי כָּל חֶפְצִי בָם: יִרְבּוּ עַצְּבוֹתָם אַחֵר מָהָרוּ, בַּל אַסִּיךְ נִסְכֵּיהֶם מִדָּם, וּבַל אֶשָּׂא אֶת שְׁמוֹתָם עַל שְׂפָתָי: יהוה, מְנָת חֶלְקִי וְכוֹסִי, אַתָּה תּוֹמִיךְ גּוֹרָלִי: חֲבָלִים נָפְלוּ לִי בַּנְּעִמִים, אַף נַחֲלָת שָׁפְרָה עָלָי: אֲבָרֵךְ אֶת יהוה אֲשֶׁר יְעָצָנִי, אַף לֵילוֹת יִסְּרוּנִי כִלְיוֹתָי: שִׁוִּיתִי יהוה לְנֶגְדִּי תָמִיד, כִּי מִימִינִי בַּל אֶמּוֹט: לָכֵן שָׂמַח לִבִּי וַיָּגֶל כְּבוֹדִי, אַף בְּשָׂרִי יִשְׁכֹּן לָבֶטַח: כִּי לֹא תַעֲזֹב נַפְשִׁי לִשְׁאוֹל, לֹא תִתֵּן חֲסִידְךָ לִרְאוֹת שָׁחַת: תּוֹדִיעֵנִי אֹרַח חַיִּים, שֹׂבַע שְׂמָחוֹת אֶת פָּנֶיךָ, נְעִמוֹת בִּימִינְךָ נֶצַח:","cond":["noShacharitTachanun"]},{"kind":"header","text":"הבדלה","cond":["havdala"]},{"kind":"instruction","text":"סדר הבדלה\n\nנוטל הכוס בידו ואומר:","cond":["havdala"]},{"kind":"text","text":"הִנֵּה אֵל יְשׁוּעָתִי אֶבְטַח וְלֹא אֶפְחָד: כִּי עָזִּי וְזִמְרָת יָהּ יהוה, וַיְהִי לִי לִישׁוּעָה: וּשְׁאַבְתֶּם מַיִם בְּשָׂשׂוֹן, מִמַּעַיְנֵי הַיְשׁוּעָה: לַיהוה הַיְשׁוּעָה, עַל עַמְּךָ בִרְכָתֶךָ סֶּלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה: יהוה צְבָאוֹת, אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ: לַיְּהוּדִים הָיְתָה אוֹרָה וְשִׂמְחָה, וְשָׂשׁוֹן וִיקָר: כֵּן תִּהְיֶה לָנוּ. כּוֹס יְשׁוּעוֹת אֶשָּׂא, וּבְשֵׁם יהוה אֶקְרָא:","cond":["havdala","sun"]},{"kind":"text","text":"סַבְרִי מָרָנָן וְרַבָּנָן וְרַבּוֹתַי.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא פְּרִי הַגָּפֶן.","cond":["havdala"]},{"kind":"instruction","text":"ואם מברך על משקה שאינו יין יברך שהכל.","cond":["havdala"]},{"kind":"instruction","text":"מוריד את הכוס ונוטל את הבשמים ומברך:","cond":["havdala","sun"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא (עֲצֵי או עִשְׂבֵּי או מִינֵי) בְשָׂמִים.","cond":["havdala","sun"]},{"kind":"instruction","text":"מברך לאור הנר:","cond":["havdala","fire"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא מְאוֹרֵי הָאֵשׁ.","cond":["havdala","fire"]},{"kind":"instruction","text":"נוטל את הכוס בידו ומברך:","cond":["havdala"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַמַּבְדִּיל בֵּין קֹדֶשׁ לְחוֹל, בֵּין אוֹר לְחֹשֶׁךְ, בֵּין יִשְׂרָאֵל לָעַמִּים, בֵּין יוֹם הַשְּׁבִיעִי לְשֵׁשֶׁת יְמֵי הַמַּעֲשֶׂה. בָּרוּךְ אַתָּה יהוה, הַמַבְדִּיל בֵּין קֹדֶשׁ לְחוֹל.","cond":["havdala"]},{"kind":"instruction","text":"אם שתה רביעית יין יברך ברכת מעין שלש (מופיע בתפריט התפילות).","cond":["havdala"]}]},"sfard":{"shacharit":[{"kind":"instruction","text":"מיד כשקם בבוקר יאמר מודה אני:","cond":[]},{"kind":"text","text":"מוֹדֶה (נשים אומרות: מוֹדָה) אֲנִי לְפָנֶיךָ מֶלֶךְ חַי וְקַיָּם שֶׁהֶחֱזַרְתָּ בִּי נִשְׁמָתִי בְּחֶמְלָה, רַבָּה אֱמוּנָתֶךָ.\n\nרֵאשִׁית חָכְמָה יִרְאַת יהוה, שֶׂכֶל טוֹב לְכָל עוֹשֵׂיהֶם, תְּהִלָּתוֹ עוֹמֶדֶת לָעַד:\nבָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד.\nתּוֹרָה צִוָּה לָנוּ מֹשֶׁה, מוֹרָשָׁה קְהִלַּת יַעֲקֹב: שְׁמַע בְּנִי מוּסַר אָבִיךָ, וְאַל תִּטּוֹשׁ תּורַת אִמֶּךָ: תּוֹרָה תְּהֵא אֱמוּנָתִי, וְאֵל שַׁדַּי בְּעֶזְרָתִי. וְאַתֶּם הַדְּבֵקִים בַּיהוה אֱלֹהֵיכֶם חַיִּים כֻּלְּכֶם הַיּוֹם: לִישׁוּעָתְךָ קִוִּיתִי יהוה:","cond":[]},{"kind":"instruction","text":"כל היום אף אם עשה צרכיו אינו מברך על נטילת ידיים רק אשר יצר:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ עַל נְטִילַת יָדָיִם.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלַם, אֲשֶׁר יָצַר אֶת הָאָדָם בְּחָכְמָה, וּבָרָא בוֹ נְקָבִים נְקָבִים, חֲלוּלִים חֲלוּלִים. גָּלוּי וְיָדוּעַ לִפְנֵי כִסֵּא כְבוֹדֶךָ, שֶׁאִם יִפָּתֵחַ אֶחָד מֵהֶם אוֹ יִסָּתֵם אֶחָד מֵהֶם, אִי אֶפְשָׁר לְהִתְקַיֵּם וְלַעֲמֹד לְפָנֶיךָ אֲפִלּוּ שָׁעָה אַחַת. בָּרוּךְ אַתָּה יהוה, רוֹפֵא כָל בָּשָׂר וּמַפְלִיא לַעֲשׂוֹת.","cond":[]},{"kind":"instruction","text":"ישתדל להצמיד ברכת אלהי נשמה לברכת אשר יצר. אם שכח ישתדל לברך את ברכת אלהי נשמה בצמוד לברכה אחרת.","cond":[]},{"kind":"text","text":"אֱלֹהַי, נְשָׁמָה שֶׁנָּתַתָּ בִּי טְהוֹרָה הִיא. אַתָּה בְרָאתָהּ, אַתָּה יְצַרְתָּהּ, אַתָּה נְפַחְתָּהּ בִּי, וְאַתָּה מְשַׁמְּרָהּ בְּקִרְבִּי, וְאַתָּה עָתִיד לִטְּלָהּ מִמֶּנִּי, וּלְהַחֲזִירָהּ בִּי לֶעָתִיד לָבוֹא. כָּל זְמַן שֶׁהַנְּשָׁמָה בְקִרְבִּי, מוֹדֶה (נשים אומרות: מוֹדָה) אֲנִי לְפָנֶיךָ, יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, רִבּוֹן כָּל הַמַּעֲשִׂים, אֲדוֹן כָּל הַנְּשָׁמוֹת. בָּרוּךְ אַתָּה יהוה, הַמַּחֲזִיר נְשָׁמוֹת לִפְגָרִים מֵתִים.","cond":[]},{"kind":"instruction","text":"סדר לבישת ציצית\n\nלפני שלובש טלית קטן מברך מעומד (ואם יתעטף בזמן הקרוב בטלית גדול לא יברך):","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ עַל מִצְוַת צִיצִית.\n\nיְהִי רָצוֹן מִלְּפָנֶיךָ, יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁתְּהֵא חֲשׁוּבָה מִצְוַת צִיצִית לְפָנֶיךָ כְּאִלּוּ קִיַּמְתִּיהָ בְּכָל פְּרָטֶיהָ וְדִקְדּוּקֶיהָ וְכַוָּנוֹתֶיהָ, וְתַרְיַ\"ג מִצְוׂת הַתְּלוּיוֹת בָּהּ, אָמֵן סֶלָה.","cond":[]},{"kind":"header","text":"ברכות התורה","cond":[]},{"kind":"instruction","text":"בכל יום בבוקר קודם ברכת התורה יאמר זאת:","cond":[]},{"kind":"text","text":"הֲרֵינִי מְכַוֵּן מֵעַתָּה עַל כָּל פְּרָט וּפְרָט מִמַּעֲשַׂי וְדִבּוּרַי וּמַחְשְׁבוֹתַי שֶׁל כָּל הַיּוֹם עַד לְמָחָר בָּעֵת הַזֹּאת, לְשֵׁם יִחוּד קֻדְשָׁא בְּרִיךְ הוּא וּשְׁכִינְתֵּהּ בְּשֵׁם כָּל יִשְׂרָאֵל לְהַכְרִיעַ אֶת עַצְמִי וְאֶת כָּל עַם בְּנֵי יִשְׂרָאֵל וְאֶת כָּל הָעוֹלָם לְכַף זְכוּת.\n\nוַהֲרֵינִי מְכַוֵּן מֵעַתָּה עַד לְמָחָר בָּעֵת הַזֹּאת בְּכָל פַּעַם שֶׁאַזְכִּיר שֵׁם הוי\"ה הַקָּדוֹשׁ, שֶׁהוּא בִּכְתִיבָתוֹ הָיָה הֹוֶה וְיִהְיֶה, וּבִקְרִיאָתוֹ אֲדֹנָי שֶׁהוּא אֲדוֹן הַכּל. וּכְשֶׁאַזְכִּיר שֵׁם אֱלֹהִים שֶׁהוּא תַּקִּיף וּבַעַל הַיְכֹלֶת וּבַעַל הַכֹּחוֹת כֻּלָם עִלַּת כָּל הָעִלּוֹת וְסִבַּת כָּל הַסִּבּוֹת וְשַׁלִּיט בְּכָל הָעוֹלָמוֹת.","cond":[]},{"kind":"instruction","text":"עצה זו אינה מועילה בפסוק ראשון של קריאת שמע.\n\nברכות התורה:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ לַעֲסֹק בְּדִבְרֵי תוֹרָה.","cond":[]},{"kind":"instruction","text":"אין עונים אמן, אלא ממשיכים מיד לברכת והערב נא, מפני שזו ברכה אחת (שו\"ע סי' מ\"ז סע' ו, ובמשנ\"ב ס\"ק י\"א-י\"ב).","cond":[]},{"kind":"text","text":"וְהַעֲרֶב נָא, יהוה אֱלֹהֵינוּ, אֶת דִּבְרֵי תוֹרָתְךָ בְּפִינוּ וּבְפִיּוֹת עַמְּךָ בֵּית יִשְׂרָאֵל, וְנִהְיֶה אֲנַחְנוּ וְצֶאֱצָאֵינוּ וְצֶאֱצָאֵי צֶאֱצָאֵינוּ וְצֶאֱצָאֵי עַמְּךָ בֵּית יִשְׂרָאֵל כֻּלָּנוּ יוֹדְעֵי שְׁמֶךָ וְלוֹמְדֵי תוֹרָתְךָ לִשְׁמָהּ. בָּרוּךְ אַתָּה יהוה, הַמְלַמֵּד תּוֹרָה לְעַמּוֹ יִשְׂרָאֵל.\n\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר בָּחַר בָּנוּ מִכָּל הָעַמִּים וְנָתַן לָנוּ אֶת תּוֹרָתוֹ. בָּרוּךְ אַתָּה יהוה, נוֹתֵן הַתּוֹרָה.\n\nוַיְדַבֵּר יהוה אֶל מֹשֶׁה לֵּאמֹר: דַּבֵּר אֶל אַהֲרֹן וְאֶל בָּנָיו לֵּאמֹר, כֹּה תְבָרְכוּ אֶת בְּנֵי יִשְׂרָאֵל, אָמוֹר לָהֶם:\nיְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ:\nיָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ:\nיִשָּׂא יהוה פָּנָיו אֵלֶיךָ וְיָשֵׂם לְךָ שָׁלוֹם:\nוְשָׂמוּ אֶת שְׁמִי עַל בְּנֵי יִשְׂרָאֵל, וַאֲנִי אֲבָרֲכֵם:\n\nאֵלּוּ דְבָרִים שֶׁאֵין לָהֶם שִׁעוּר: הַפֵּאָה וְהַבִּכּוּרִים וְהָרֵאָיוֹן וּגְמִילוּת חֲסָדִים וְתַלְמוּד תּוֹרָה.\n\nאֵלּוּ דְבָרִים שֶׁאָדָם אוֹכֵל פֵּרוֹתֵיהֶם בָּעוֹלָם הַזֶּה וְהַקֶּרֶן קַיֶּמֶת לוֹ לָעוֹלָם הַבָּא, וְאֵלּוּ הֵן: כִּבּוּד אָב וָאֵם, וּגְמִילוּת חֲסָדִים, וְהַשְׁכָּמַת בֵּית הַמִּדְרָשׁ שַׁחֲרִית וְעַרְבִית, וְהַכְנָסַת אוֹרְחִים, וּבִקּוּר חוֹלִים, וְהַכְנָסַת כַּלָּה, וּלְוָיַת הַמֵּת, וְעִיּוּן תְּפִלָּה, וַהֲבָאַת שָׁלוֹם בֵּין אָדָם לַחֲבֵרוֹ וּבֵין אִישׁ לְאִשְׁתּוֹ. וְתַלְמוּד תּוֹרָה כְּנֶגֶד כֻּלָּם.","cond":[]},{"kind":"header","text":"עטיפה בטלית","cond":["noTishaaBeav"]},{"kind":"instruction","text":"סדר לבישת טלית גדול\n\nיכוון בהתעטפו בטלית שציונו זאת הקב\"ה כדי לזכור כל מצוותיו לעשותם. לוקח הטלית ובודק ציציותיו אם הן כשרות, מפריד חוטיהן ואומר:","cond":["noTishaaBeav"]},{"kind":"text","text":"בָּרְכִי נַפְשִׁי אֶת יהוה, יהוה אֱלֹהַי גָּדַלְתָּ מְּאֹד, הוֹד וְהָדָר לָבָשְׁתָּ: עֹטֶה אוֹר כַּשַּׂלְמָה, נוֹטֶה שָׁמַיִם כַּיְרִיעָה:","cond":["noTishaaBeav"]},{"kind":"instruction","text":"יש אומרים:","cond":["noTishaaBeav"]},{"kind":"text","text":"לְשֵׁם יִחוּד קֻדְשָׁא בְּרִיךְ הוּא וּשְׁכִינְתֵּיהּ, בִּדְחִילוּ וּרְחִימוּ, לְיַחֵד שֵׁם י\"ה בְּו\"ה בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל יִשְׂרָאֵל, הֲרֵינִי מִתְעַטֵּף בַּצִּיצִית, כֵּן תִּתְעַטֵּף נִשְׁמָתִי וּרְמַ\"ח אֵיבָרַי וּשְׁסָ\"ה גִידַי בְּאוֹר הַצִּיצִית הָעוֹלָה תַרְיַ\"ג. וּכְשֵׁם שֶׁאֲנִי מִתְכַּסֶּה בְּטַלִּית בָּעוֹלָם הַזֶּה, כַּךְ אֶזְכֶּה לַחֲלוּקָא דְרַבָּנָן, וּלְטַלִּית נָאָה לָעוֹלָם הַבָּא בְּגַן עֵדֶן. וְעַל יְדֵי מִצְוַת צִיצִית, תִּנָּצֵל נַפְשִׁי וְרוּחִי וְנִשְׁמָתִי וּתְפִלָּתִי מִן הַחִיצוֹנִים. וְהַטַּלִּית תִּפְרוֹשׂ כְּנָפֶיהָ עֲלֵיהֶם, וְתַצִּילֵם כְּנֶשֶׁר יָעִיר קִנּוֹ עַל גּוֹזָלָיו יְרַחֵף. וּתְהֵא חֲשׁוּבָה מִצְוַת צִיצִית לִפְנֵי הַקָּדוֹשׁ בָּרוּךְ הוּא כְּאִלּוּ קִיַּמְתִּיהָ בְּכָל פְּרָטֶיהָ וְדִקְדּוּקֶיהָ וְכַוָּנוֹתֶיהָ וְתַרְיַ\"ג מִצְוׂת הַתְּלוּיוֹת בָּהּ. אָמֵן סֶלָה.","cond":["noTishaaBeav"]},{"kind":"instruction","text":"אוחז את הטלית בשתי ידיו ויברך מעומד:","cond":["noTishaaBeav"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ לְהִתְעַטֵּף בְּצִיצִית.","cond":["noTishaaBeav"]},{"kind":"instruction","text":"יתעטף בטלית ויכסה בה את ראשו ויישאר כך מעוטף איזה פרק זמן, ולאחר מכן יסיר העיטוף ויישאר לבוש בטלית.\n\nאחרי העטיפה יאמר:","cond":["noTishaaBeav"]},{"kind":"text","text":"מַה יָּקָר חַסְדְּךָ אֱלֹהִים, וּבְנֵי אָדָם בְּצֵל כְּנָפֶיךָ יֶחֱסָיוּן: יִרְוְיֻן מִדֶּשֶׁן בֵּיתֶךָ וְנַחַל עֲדָנֶיךָ תַשְׁקֵם: כִּי עִמְּךָ מְקוֹר חַיִּים, בְּאוֹרְךָ נִרְאֶה אוֹר: מְשֹׁךְ חַסְדְּךָ לְיֹדְעֶיךָ וְצִדְקָתְךָ לְיִשְׁרֵי לֵב:","cond":["noTishaaBeav"]},{"kind":"header","text":"הנחת תפילין","cond":["noTishaaBeav"]},{"kind":"instruction","text":"הנחת תפילין","cond":["noTishaaBeav"]},{"kind":"instruction","text":"פוסקי אשכנז פסקו שבחול המועד מניחים תפילין. למרות זאת, פשט המנהג בחלק מהקהילות שלא להניח. לכן, כל אחד יעשה כמנהגו. ויש פוסקים שכתבו שיניח ללא ברכה. מי שמתפלל בקהילה שבה לא מניחים תפילין גם הוא לא יניח בבית הכנסת אלא בביתו.","cond":["noTishaaBeav","pesach"]},{"kind":"instruction","text":"פוסקי אשכנז פסקו שבחול המועד מניחים תפילין. למרות זאת, פשט המנהג בחלק מהקהילות שלא להניח. לכן, כל אחד יעשה כמנהגו. ויש פוסקים שכתבו שיניח ללא ברכה. מי שמתפלל בקהילה שבה לא מניחים תפילין גם הוא לא יניח בבית הכנסת אלא בביתו.","cond":["noTishaaBeav","sucot"]},{"kind":"instruction","text":"יש אומרים:","cond":["noTishaaBeav"]},{"kind":"text","text":"לְשֵׁם יִחוּד קֻדְשָׁא בְּרִיךְ הוּא וּשְׁכִינְתֵּיהּ בִּדְחִילוּ וּרְחִימוּ, לְיַחֵד שֵׁם י\"ה בְּו\"ה בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל יִשְׂרָאֵל, הִנְנִי מְכַוֵּן בַּהֲנָחַת תְּפִלִּין לְקַיֵּם מִצְוַת בּוֹרְאִי, שֶׁצִּוָּנוּ לְהָנִיחַ תְּפִלִּין, כַּכָּתוּב בְּתוֹרָתוֹ: וּקְשַׁרְתָּם לְאוֹת עַל יָדֶךָ, וְהָיוּ לְטֹטָפֹת בֵּין עֵינֶיךָ: וְהֵם אַרְבַּע פַּרְשִׁיּוֹת אֵלּוּ: \"שְׁמַע\", \"וְהָיָה אִם שָׁמֹעַ\", \"קַדֶּשׁ לִי\", \"וְהָיָה כִּי יְבִיאֲךָ\", שֶׁיֵּשׁ בָּהֶם יִחוּדוֹ וְאַחְדוּתוֹ יִתְבָּרַךְ שְׁמוֹ בָּעוֹלָם, וְשֶׁנִּזְכֹּר נִסִּים וְנִפְלָאוֹת, שֶׁעָשָׂה עִמָּנוּ בְּהוֹצִיאוֹ אוֹתָנוּ מִמִּצְרָיִם, וַאֲשֶׁר לוֹ הַכֹּחַ וְהַמֶּמְשָׁלָה בָּעֶלְיוֹנִים וּבַתַּחְתּוֹנִים לַעֲשׂוֹת בָּהֶם כִּרְצוֹנוֹ. וְצִוָּנוּ לְהָנִיחַ עַל הַיָּד לְזִכְרוֹן זְרוֹעַ הַנְּטוּיָה, וְשֶׁהִיא נֶגֶד הַלֵּב לְשַׁעְבֵּד בָּזֶה תַּאֲווֹת וּמַחְשְׁבוֹת לִבֵּנוּ לַעֲבוֹדָתוֹ יִתְבָּרַךְ שְׁמוֹ, וְעַל הָרֹאשׁ נֶגֶד הַמֹּחַ, שֶׁהַנְּשָׁמָה שֶׁבְּמֹחִי עִם שְׁאָר חוּשַׁי וְכֹחוֹתַי כֻּלָּם יִהְיוּ מְשֻׁעְבָּדִים לַעֲבוֹדָתוֹ יִתְבָּרַךְ שְׁמוֹ. וּמִשֶּׁפַע מִצְוַת תְּפִלִּין יִתְמַשֵּׁךְ עָלַי לִהְיוֹת לִי חַיִּים אֲרֻכִּים וְשֶׁפַע קֹדֶשׁ וּמַחֲשָׁבוֹת קְדוֹשׁוֹת, בְּלִי הִרְהוּר חֵטְא וְעָוׂן כְּלָל, וְשֶׁלּא יְפַתֵּנוּ וְלֹא יִתְגָּרֶה בָּנוּ יֵצֶר הָרָע, וִינִיחֵנוּ לַעֲבֹד אֶת יהוה כַּאֲשֶׁר עִם לְבָבֵנוּ. וִיהִי רָצוֹן מִלְּפָנֶיךָ, יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתְּהֵא חֲשׁוּבָה מִצְוַת הֲנָחַת תְּפִלִּין לִפְנֵי הַקָּדושׁ בָּרוּךְ הוּא כְּאִלּוּ קִיַּמְתִּיהָ בְּכָל פְּרָטֶיהָ וְדִקְדּוּקֶיהָ וְכַוָּנוֹתֶיהָ וְתַרְיַ\"ג מִצְוׂת הַתְּלוּיוֹת בָּהּ, אָמֵן סֶלָה.","cond":["noTishaaBeav"]},{"kind":"instruction","text":"יש אומרים שמברכים רק ברכה אחת על התפילין, והיא ברכת \"להניח תפילין\", ואם שח בין של יד לשל ראש, מברך על של ראש \"על מצות תפילין\". אבל המנהג העיקרי באשכנז הוא לברך \"על מצות תפילין\" על של ראש בכל מקרה בלחש, ולומר לאחר מכן \"ברוך שם כבוד מלכותו לעולם ועד\" שמא היתה זו ברכה לבטלה. על פי שיטה זו, אם שח בין של יד לשל ראש, מברך על של ראש את שתי הברכות.\n\nיניח את התפילה של יד במקומה ולפני הקשירה יברך:","cond":["noTishaaBeav"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ לְהָנִיחַ תְּפִלִּין.","cond":["noTishaaBeav"]},{"kind":"instruction","text":"יהדק את הרצועה ויכרוך שבע כריכות סביב הזרוע, ולאחר מכן יניח התפילה של ראש במקומה, ולפני ההידוק יברך בלחש (ויש אומרים שלא יברך):","cond":["noTishaaBeav"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ עַל מִצְוַת תְּפִלִּין.","cond":["noTishaaBeav"]},{"kind":"instruction","text":"ומהדקו בראשו ואומר:","cond":["noTishaaBeav"]},{"kind":"text","text":"בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד:","cond":["noTishaaBeav"]},{"kind":"instruction","text":"יש אומרים:","cond":["noTishaaBeav"]},{"kind":"text","text":"וּמֵחָכְמָתְךָ אֵל עֶלְיוֹן תַּאֲצִיל עָלַי, וּמִבִּינָתְךָ תְּבִינֵנִי, וּבְחַסְדְּךָ תַּגְדִּיל עָלַי, וּבִגְבוּרָתְךָ תַּצְמִית אוֹיְבַי וְקָמַי. וְשֶׁמֶן הַטּוֹב תָּרִיק עַל שִׁבְעָה קְנֵי הַמְּנוֹרָה, לְהַשְׁפִּיעַ טוּבְךָ לִבְרִיּוֹתֶיךָ. פּוֹתֵחַ אֶת יָדֶךָ וּמַשְׂבִּיעַ לְכָל חַי רָצוֹן:","cond":["noTishaaBeav"]},{"kind":"instruction","text":"אחר כך יכרוך שלש כריכות סביב האצבע האמצעית ויכרוך בתחלה כריכה אחת בפרק האמצעי ואחר כך אחת בראש פרק התחתון ואחת בסוף פרק התחתון ואומר:","cond":["noTishaaBeav"]},{"kind":"text","text":"וְאֵרַשְׂתִּיךְ לִי לְעוֹלָם: וְאֵרַשְׂתִּיךְ לִי בְּצֶדֶק וּבְמִשְׁפָּט וּבְחֶסֶד וּבְרַחֲמִים: וְאֵרַשְׂתִּיךְ לִי בֶּאֱמוּנָה, וְיָדַעַתְּ אֶת יהוה:","cond":["noTishaaBeav"]},{"kind":"instruction","text":"אחר הנחת תפלין יאמר שתי פרשיות אלה:","cond":["noTishaaBeav"]},{"kind":"text","text":"וַיְדַבֵּר יהוה אֶל מֹשֶׁה לֵּאמֹר: קַדֶּשׁ לִי כָל בְּכוֹר פֶּטֶר כָּל רֶחֶם בִּבְנֵי יִשְׂרָאֵל בָּאָדָם וּבַבְּהֵמָה, לִי הוּא: וַיֹּאמֶר מֹשֶׁה אֶל הָעָם זָכוֹר אֶת הַיּוֹם הַזֶּה אֲשֶׁר יְצָאתֶם מִמִּצְרַיִם מִבֵּית עֲבָדִים, כִּי בְּחֹזֶק יָד הוֹצִיא יהוה אֶתְכֶם מִזֶּה, וְלֹא יֵאָכֵל חָמֵץ: הַיּוֹם אַתֶּם יֹצְאִים, בְּחֹדֶשׁ הָאָבִיב: וְהָיָה כִי יְבִיאֲךָ יהוה אֶל אֶרֶץ הַכְּנַעֲנִי וְהַחִתִּי וְהָאֱמֹרִי וְהַחִוִּי וְהַיְבוּסִי אֲשֶׁר נִשְׁבַּע לַאֲבֹתֶיךָ לָתֶת לָךְ, אֶרֶץ זָבַת חָלָב וּדְבָשׁ, וְעָבַדְתָּ אֶת הָעֲבֹדָה הַזֹּאת בַּחֹדֶשׁ הַזֶּה: שִׁבְעַת יָמִים תֹּאכַל מַצֹּת וּבַיּוֹם הַשְּׁבִיעִי חַג לַיהוה: מַצּוֹת יֵאָכֵל אֵת שִׁבְעַת הַיָּמִים, וְלֹא יֵרָאֶה לְךָ חָמֵץ וְלֹא יֵרָאֶה לְךָ שְׂאֹר בְּכָל גְּבֻלֶךָ: וְהִגַּדְתָּ לְבִנְךָ בַּיּוֹם הַהוּא לֵאמֹר, בַּעֲבוּר זֶה עָשָׂה יהוה לִי בְּצֵאתִי מִמִּצְרָיִם: וְהָיָה לְךָ לְאוֹת עַל יָדְךָ וּלְזִכָּרוֹן בֵּין עֵינֶיךָ, לְמַעַן תִּהְיֶה תּוֹרַת יהוה בְּפִיךָ, כִּי בְּיָד חֲזָקָה הוֹצִאֲךָ יהוה מִמִּצְרָיִם: וְשָׁמַרְתָּ אֶת הַחֻקָּה הַזֹּאת לְמוֹעֲדָהּ, מִיָּמִים יָמִימָה:\n\nוְהָיָה כִּי יְבִאֲךָ יהוה אֶל אֶרֶץ הַכְּנַעֲנִי כַּאֲשֶׁר נִשְׁבַּע לְךָ וְלַאֲבֹתֶיךָ, וּנְתָנָהּ לָךְ: וְהַעֲבַרְתָּ כָל פֶּטֶר רֶחֶם לַיהוה, וְכָל פֶּטֶר שֶׁגֶר בְּהֵמָה אֲשֶׁר יִהְיֶה לְךָ הַזְּכָרִים לַיהוה: וְכָל פֶּטֶר חֲמֹר תִּפְדֶּה בְשֶׂה, וְאִם לֹא תִפְדֶּה וַעֲרַפְתּוֹ, וְכֹל בְּכוֹר אָדָם בְּבָנֶיךָ תִּפְדֶּה: וְהָיָה כִּי יִשְׁאָלְךָ בִנְךָ מָחָר לֵּאמֹר מַה זֹּאת, וְאָמַרְתָּ אֵלָיו, בְּחֹזֶק יָד הוֹצִיאָנוּ יהוה מִמִּצְרַיִם מִבֵּית עֲבָדִים: וַיְהִי כִּי הִקְשָׁה פַרְעֹה לְשַׁלְּחֵנוּ, וַיַּהֲרֹג יהוה כָּל בְּכוֹר בְּאֶרֶץ מִצְרַיִם, מִבְּכֹר אָדָם וְעַד בְּכוֹר בְּהֵמָה, עַל כֵּן אֲנִי זֹבֵחַ לַיהוה כָּל פֶּטֶר רֶחֶם הַזְּכָרִים וְכָל בְּכוֹר בָּנַי אֶפְדֶּה: וְהָיָה לְאוֹת עַל יָדְכָה וּלְטוֹטָפֹת בֵּין עֵינֶיךָ, כִּי בְּחֹזֶק יָד הוֹצִיאָנוּ יהוה מִמִּצְרָיִם:","cond":["noTishaaBeav"]},{"kind":"header","text":"מה טובו","cond":[]},{"kind":"instruction","text":"כשנכנס לבית הכנסת יאמר זה:","cond":[]},{"kind":"text","text":"מַה טֹּבוּ אֹהֲלֶיךָ יַעֲקֹב, מִשְׁכְּנֹתֶיךָ יִשְׂרָאֵל: וַאֲנִי בְּרֹב חַסְדְּךָ אָבוֹא בֵיתֶךָ, אֶשְׁתַּחֲוֶה אֶל הֵיכַל קָדְשְׁךָ בְּיִרְאָתֶךָ: יהוה, אָהַבְתִּי מְעוֹן בֵּיתֶךָ וּמְקוֹם מִשְׁכַּן כְּבוֹדֶךָ: וַאֲנִי אֶשְׁתַּחֲוֶה וְאֶכְרָעָה, אֶבְרְכָה לִפְנֵי יהוה עֹשִׂי. וַאֲנִי תְפִלָּתִי לְךָ, יהוה, עֵת רָצוֹן, אֱלֹהִים בְּרֹב חַסְדֶּךָ, עֲנֵנִי בֶּאֱמֶת יִשְׁעֶךָ:","cond":[]},{"kind":"instruction","text":"פיוטים","cond":[]},{"kind":"text","text":"אֲדוֹן עוֹלָם אֲשֶׁר מָלַךְ, בְּטֶרֶם כָּל יְצִיר נִבְרָא. לְעֵת נַעֲשָׂה בְחֶפְצוֹ כֹּל, אֲזַי מֶלֶךְ שְׁמוֹ נִקְרָא. וְאַחֲרֵי כִּכְלוֹת הַכֹּל, לְבַדּוֹ יִמְלֹךְ נוֹרָא. וְהוּא הָיָה וְהוּא הֹוֶה, וְהוּא יִהְיֶה בְּתִפְאָרָה. וְהוּא אֶחָד וְאֵין שֵׁנִי, לְהַמְשִׁיל לוֹ לְהַחְבִּירָה. בְּלִי רֵאשִׁית בְּלִי תַכְלִית, וְלוֹ הָעֹז וְהַמִּשְׂרָה. וְהוּא אֵלִי וְחַי גוֹאֲלִי, וְצוּר חֶבְלִי בְּעֵת צָרָה. וְהוּא נִסִּי וּמָנוֹס לִי, מְנָת כּוֹסִי בְּיוֹם אֶקְרָא. בְּיָדוֹ אַפְקִיד רוּחִי, בְּעֵת אִישָׁן וְאָעִירָה. וְעִם רוּחִי גְּוִיָּתִי, יהוה לִי וְלֹא אִירָא.","cond":[]},{"kind":"text","text":"יִגְדַּל אֱלֹהִים חַי וְיִשְׁתַּבַּח, נִמְצָא וְאֵין עֵת אֶל מְצִיאוּתוֹ. אֶחָד וְאֵין יָחִיד כְּיִחוּדוֹ, נֶעְלָם וְגַם אֵין סוֹף לְאַחְדוּתוֹ. אֵין לוֹ דְּמוּת הַגּוּף וְאֵינוֹ גוּף, לֹא נַעֲרֹךְ אֵלָיו קְדֻשָּׁתוֹ. קַדְמוֹן לְכָל דָבָר אֲשֶׁר נִבְרָא, רִאשׁוֹן וְאֵין רֵאשִׁית לְרֵאשִׁיתוֹ. הִנּוֹ אֲדוֹן עוֹלָם לְכָל נוֹצָר, יוֹרֶה גְדֻלָּתוֹ וּמַלְכוּתוֹ. שֶׁפַע נְבוּאָתוֹ נְתָנוֹ, אֶל אַנְשֵׁי סְגֻלָּתוֹ וְתִפְאַרְתּוֹ. לֹא קָם בְּיִשְׂרָאֵל כְּמֹשֶׁה עוֹד, נָבִיא וּמַבִּיט אֶת תְּמוּנָתוֹ. תּוֹרַת אֱמֶת נָתַן לְעַמּוֹ אֵל, עַל יַד נְבִיאוֹ נֶאֱמַן בֵּיתוֹ. לֹא יַחֲלִיף הָאֵל וְלֹא יָמִיר דָתוֹ, לְעוֹלָמִים לְזוּלָתוֹ. צוֹפֶה וְיוֹדֵעַ סְתָרֵינוּ, מַבִּיט לְסוֹף דָבָר בְּקַדְמָתוֹ. גּוֹמֵל לְאִישׁ-חֶסֶד כְּמִפְעָלוֹ, נוֹתֵן לְרָשָׁע רָע כְּרִשְׁעָתוֹ. יִשְׁלַח לְקֵץ הַיָּמִין מְשִׁיחֵנוּ, לִפְדּוֹת מְחַכֵּי קֵץ יְשׁוּעָתוֹ. מֵתִים יְחַיֶּה אֵל בְּרֹב חַסְדּוֹ, בָּרוּךְ עֲדֵי-עַד שֵׁם תְּהִלָּתוֹ.","cond":[]},{"kind":"header","text":"ברכות השחר","cond":[]},{"kind":"instruction","text":"ברכות השחר","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר נָתַן לַשֶּׂכְוִי בִינָה לְהַבְחִין בֵּין יוֹם וּבֵין לָיְלָה.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁלֹּא עָשַׂנִי גּוֹי (לנקבה: גּוֹיָה).\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁלֹּא עָשַׂנִי עָבֶד (לנקבה: שִׁפְחָה).\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁלֹּא עָשַׂנִי אִשָּׁה (לנקבה: שֶׁעָשַׂנִי כִּרְצוֹנוֹ).\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, פּוֹקֵחַ עִוְרִים.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, מַלְבִּישׁ עֲרֻמִּים.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, מַתִּיר אֲסוּרִים.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, זוֹקֵף כְּפוּפִים.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, רוֹקַע הָאָרֶץ עַל הַמָּיִם.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַמֵּכִין מִצְעֲדֵי גָבֶר.","cond":[]},{"kind":"instruction","text":"יש שאינם מברכים ברכת \"שעשה לי כל צרכי\" בתשעה באב. ויש אומרים שאפשר לברך אם מתכוון במוצאי הצום לנעול את נעליו הרגילות.","cond":["tishaaBeav"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁעָשַׂה לִּי כָּל צָרְכִּי.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אוֹזֵר יִשְׂרָאֵל בִּגְבוּרָה.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, עוֹטֵר יִשְׂרָאֵל בְּתִפְאָרָה.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַנּוֹתֵן לַיָּעֵף כֹּחַ.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַמַּעֲבִיר שֵׁנָה מֵעֵינָי וּתְנוּמָה מֵעַפְעַפָּי. וִיהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתַּרְגִּילֵנוּ בְּתוֹרָתֶךָ, וְדַבְּקֵנוּ בְּמִצְוׂתֶיךָ, וְאַל תְּבִיאֵנוּ לֹא לִידֵי חֵטְא, וְלֹא לִידֵי עֲבֵרָה וְעָוׂן, וְלֹא לִידֵי נִסָּיוֹן, וְלֹא לִידֵי בִזָּיוֹן, וְאַל יִשְׁלֹט בָּנוּ יֵצֶר הָרָע, וְהַרְחִיקֵנוּ מֵאָדָם רָע וּמֵחָבֵר רָע, וְדַבְּקֵנוּ בְּיֵצֶר הַטוֹב וּבְמַעֲשִׂים טוֹבִים, וְכֹף אֶת יִצְרֵנוּ לְהִשְׁתַּעְבֶּד לָךְ, וּתְנֵנוּ הַיּוֹם וּבְכָל יוֹם לְחֵן וּלְחֶסֶד וּלְרַחֲמִים בְּעֵינֶיךָ וּבְעֵינֵי כָל רוֹאֵינוּ, וְתִגְמְלֵנוּ חֲסָדִים טוֹבִים. בָּרוּךְ אַתָּה יהוה, הַגּוֹמֵל חֲסָדִים טוֹבִים לְעַמּו יִשְׂרָאֵל.\n\nיְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁתַּצִּילֵנִי הַיּוֹם וּבְכָל יוֹם מֵעַזֵּי פָנִים וּמֵעַזּוּת פָּנִים, מֵאָדָם רָע, מִיֵּצֶר רָע, וּמֵחָבֵר רָע, וּמִשָּׁכֵן רָע, וּמִפֶּגַע רָע, מֵעַיִן הָרָע, מִלָּשׁוֹן הָרָע, מִמַּלְשִׁינוּת, מֵעֵדוּת שֶׁקֶר, מִשִּׂנְאַת הַבְּרִיּוֹת, מֵעֲלִילָה, מִמִּיתָה מְשֻׁנָּה, מֵחֳלָיִם רָעִים, מִמִּקְרִים רָעִים וּמִשָּׂטָן הַמַּשְׁחִית, מִדִּין קָשֶׁה וּמִבַּעַל דִּין קָשֶׁה, בֵּין שֶׁהוּא בֶן בְּרִית וּבֵין שֶׁאֵינוֹ בֶן בְּרִית, וּמִדִּינָה שֶׁל גֵּיהִנֹּם.","cond":[]},{"kind":"header","text":"פרשת העקדה","cond":[]},{"kind":"instruction","text":"פרשת העקדה","cond":[]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, זָכְרֵנוּ בְּזִכְרוֹן טוֹב לְפָנֶיךָ, וּפָקְדֵנוּ בִּפְקוּדת יְשׁוּעָה וְרַחֲמִים מִשְּׁמֵי שְׁמֵי קֶדֶם, וּזְכָר לָנוּ יהוה אֱלֹהֵינוּ אַהֲבַת הַקַּדְמוֹנִים אַבְרָהָם יִצְחָק וְיִשְׂרָאֵל עֲבָדֶיךָ, אֶת הַבְּרִית וְאֶת הַחֶסֶד וְאֶת הַשְּׁבוּעָה שֶׁנִּשְׁבַּעְתָּ לְאַבְרָהָם אָבִינוּ בְּהַר הַמּוֹרִיָּה, וְאֶת הָעֲקֵדָה שֶׁעָקַד אֶת יִצְחָק בְּנוֹ עַל גַּבֵּי הַמִּזְבֵּחַ, כַּכָּתוּב בְּתוֹרָתָךְ:","cond":[]},{"kind":"text","text":"וַיְהִי אַחַר הַדְּבָרִים הָאֵלֶּה, וְהָאֱלֹהִים נִסָּה אֶת אַבְרָהָם, וַיֹּאמֶר אֵלָיו אַבְרָהָם, וַיֹּאמֶר הִנֵּנִי: וַיֹּאמֶר קַח נָא אֶת בִּנְךָ אֶת יְחִידְךָ אֲשֶׁר אָהַבְתָּ אֶת יִצְחָק, וְלֶךְ לְךָ אֶל אֶרֶץ הַמֹּרִיָּה, וְהַעֲלֵהוּ שָׁם לְעֹלָה עַל אַחַד הֶהָרִים אֲשֶׁר אֹמַר אֵלֶיךָ: וַיַּשְׁכֵּם אַבְרָהָם בַּבֹּקֶר וַיַּחֲבֹשׁ אֶת חֲמֹרוֹ, וַיִּקַּח אֶת שְׁנֵי נְעָרָיו אִתּוֹ וְאֵת יִצְחָק בְּנוֹ, וַיְבַקַּע עֲצֵי עֹלָה וַיָּקָם וַיֵּלֶךְ אֶל הַמָּקוֹם אֲשֶׁר אָמַר לוֹ הָאֱלֹהִים: בַּיּוֹם הַשְּׁלִישִׁי וַיִּשָּׂא אַבְרָהָם אֶת עֵינָיו, וַיַּרְא אֶת הַמָּקום מֵרָחוֹק: וַיֹּאמֶר אַבְרָהָם אֶל נְעָרָיו שְׁבוּ לָכֶם פֹּה עִם הַחֲמוֹר, וַאֲנִי וְהַנַּעַר נֵלְכָה עַד כֹּה, וְנִשְׁתַּחֲוֶה וְנָשׁוּבָה אֲלֵיכֶם: וַיִּקַּח אַבְרָהָם אֶת עֲצֵי הָעֹלָה וַיָּשֶׂם עַל יִצְחָק בְּנוֹ, וַיִּקַּח בְּיָדוֹ אֶת הָאֵשׁ וְאֶת הַמַּאֲכֶלֶת, וַיֵּלְכוּ שְׁנֵיהֶם יַחְדָּו: וַיֹּאמֶר יִצְחָק אֶל אַבְרָהָם אָבִיו וַיֹּאמֶר אָבִי, וַיֹּאמֶר הִנֶּנִּי בְנִי, וַיֹּאמֶר הִנֵּה הָאֵשׁ וְהָעֵצִים וְאַיֵּה הַשֶּׂה לְעֹלָה: וַיֹּאמֶר אַבְרָהָם: אֱלֹהִים יִרְאֶה לּוֹ הַשֶּׂה לְעֹלָה בְּנִי, וַיֵּלְכוּ שְׁנֵיהֶם יַחְדָּו: וַיָּבֹאוּ אֶל הַמָּקוֹם אֲשֶׁר אָמַר לוֹ הָאֱלֹהִים, וַיִּבֶן שָׁם אַבְרָהָם אֶת הַמִּזְבֵּחַ וַיַּעֲרֹךְ אֶת הָעֵצִים, וַיַּעֲקֹד אֶת יִצְחָק בְּנוֹ, וַיָּשֶׂם אֹתוֹ עַל הַמִּזְבֵּחַ מִמַּעַל לָעֵצִים: וַיִּשְׁלַח אַבְרָהָם אֶת יָדוֹ וַיִּקַּח אֶת הַמַּאֲכֶלֶת לִשְׁחֹט אֶת בְּנוֹ: וַיִּקְרָא אֵלָיו מַלְאַךְ יהוה מִן הַשָּׁמַיִם וַיֹּאמֶר אַבְרָהָם אַבְרָהָם, וַיֹּאמֶר הִנֵּנִי: וַיֹּאמֶר אַל תִּשְׁלַח יָדְךָ אֶל הַנַּעַר וְאַל תַּעַשׂ לוֹ מְאוּמָה, כִּי עַתָּה יָדַעְתִּי כִּי יְרֵא אֱלֹהִים אַתָּה וְלֹא חָשַׂכְתָּ אֶת בִּנְךָ אֶת יְחִידְךָ מִמֶּנִּי: וַיִּשָּׂא אַבְרָהָם אֶת עֵינָיו וַיַּרְא וְהִנֵּה אַיִל, אַחַר נֶאֱחַז בַּסְּבַךְ בְּקַרְנָיו, וַיֵּלֶךְ אַבְרָהָם וַיִּקַּח אֶת הָאַיִל, וַיַּעֲלֵהוּ לְעֹלָה תַּחַת בְּנוֹ: וַיִּקְרָא אַבְרָהָם שֵׁם הַמָּקוֹם הַהוּא יהוה יִרְאֶה, אֲשֶׁר יֵאָמֵר הַיּוֹם בְּהַר יהוה יֵרָאֶה: וַיִּקְרָא מַלְאַךְ יהוה אֶל אַבְרָהָם, שֵׁנִית מִן הַשָּׁמָיִם: וַיֹּאמֶר בִּי נִשְׁבַּעְתִּי נְאֻם יהוה, כִּי יַעַן אֲשֶׁר עָשִׂיתָ אֶת הַדָּבָר הַזֶּה וְלֹא חָשַׂכְתָּ אֶת בִּנְךָ אֶת יְחִידֶךָ: כִּי בָרֵךְ אֲבָרֶכְךָ וְהַרְבָּה אַרְבֶּה אֶת זַרְעֲךָ כְּכוֹכְבֵי הַשָּׁמַיִם וְכַחוֹל אֲשֶׁר עַל שְׂפַת הַיָּם, וְיִרַשׁ זַרְעֲךָ אֵת שַׁעַר אֹיְבָיו: וְהִתְבָּרְכוּ בְזַרְעֲךָ כֹּל גּוֹיֵי הָאָרֶץ, עֵקֶב אֲשֶׁר שָׁמַעְתָּ בְּקֹלִי: וַיָּשָׁב אַבְרָהָם אֶל נְעָרָיו וַיָּקֻמוּ וַיֵּלְכוּ יַחְדָּו אֶל בְּאֵר שָׁבַע, וַיֵּשֶׁב אַבְרָהָם בִּבְאֵר שָׁבַע:","cond":[]},{"kind":"text","text":"רִבּוֹנוֹ שֶׁל עוֹלָם, כְּמוֹ שֶׁכָּבַשׁ אַבְרָהָם אָבִינוּ אֶת רַחֲמָיו לַעֲשׂוֹת רְצוֹנְךָ בְּלֵבָב שָׁלֵם, כֵּן יִכְבְּשׁוּ רַחֲמֶיךָ אֶת כַּעַסְךָ מֵעָלֵינוּ וְיִגֹּלּוּ רַחֲמֶיךָ עַל מִדּוֹתֶיךָ. וְתִתְנַהֵג עִמָּנוּ יהוה אֱלֹהֵינוּ בְּמִדַּת הַחֶסֶד וּבְמִדַּת הָרַחֲמִים, וּבְטוּבְךָ הַגָּדוֹל יָשׁוּב חֲרוֹן אַפְּךָ מֵעַמְּךָ וּמֵעִירְךָ וּמֵאַרְצְךָ וּמִנַּחֲלָתֶךָ. וְקַיֶּם לָנוּ יהוה אֱלֹהֵינוּ אֶת הַדָּבָר שֶׁהִבְטַחְתָּנוּ בְּתוֹרָתֶךָ עַל יְדֵי משֶׁה עַבְדֶּךָ כָּאָמוּר: וְזָכַרְתִּי אֶת בְּרִיתִי יַעֲקוֹב, וְאַף אֶת בְּרִיתִי יִצְחָק, וְאַף אֶת בְּרִיתִי אַבְרָהָם אֶזְכֹּר וְהָאָרֶץ אֶזְכֹּר: וְנֶאֱמַר: וְאַף גַּם זֹאת בִּהְיוֹתָם בְּאֶרֶץ אֹיְבֵיהֶם, לֹא מְאַסְתִּים וְלֹא גְעַלְתִּים לְכַלּוֹתָם, לְהָפֵר בְּרִיתִי אִתָּם, כִּי אֲנִי יהוה אֱלֹהֵיהֶם: וְנֶאֱמַר: וְזָכַרְתִּי לָהֶם בְּרִית רִאשֹׁנִים, אֲשֶׁר הוֹצֵאתִי אֹתָם מֵאֶרֶץ מִצְרַיִם לְעֵינֵי הַגּוֹיִם, לִהְיוֹת לָהֶם לֵאֱלֹהִים, אֲנִי יהוה: וְנֶאֱמַר: וְשָׁב יהוה אֱלֹהֶיךָ אֶת שְׁבוּתְךָ וְרִחֲמֶךָ, וְשָׁב וְקִבֶּצְךָ מִכָּל הָעַמִּים אֲשֶׁר הֱפִיצְךָ יהוה אֱלֹהֶיךָ שָׁמָּה: אִם יִהְיֶה נִדַּחֲךָ בִּקְצֵה הַשָּׁמָיִם, מִשָּׁם יְקַבֶּצְךָ יהוה אֱלֹהֶיךָ וּמִשָּׁם יִקָּחֶךָ: וְנֶאֱמַר: וֶהֱבִיאֲךָ יהוה אֱלֹהֶיךָ אֶל הָאָרֶץ אֲשֶׁר יָרְשׁוּ אֲבוֹתֶיךָ וִירִשְׁתָּהּ, וְהֵיטִבְךָ וְהִרְבְּךָ מֵאֲבוֹתֶיךָ: וְנֶאֱמַר: יהוה חָנֵּנוּ, לְךָ קִוִּינוּ, הֱיֵה זְרוֹעָם לַבְּקָרִים אַף יְשׁוּעָתֵנוּ בְּעֵת צָרָה: וְנֶאֱמַר: וְעֵת צָרָה הִיא לְיַעֲקֹב וּמִמֶּנָּה יִוָּשֵׁעַ: וְנֶאֱמַר: בְּכָל צָרָתָם לוֹ צָר וּמַלְאַךְ פָּנָיו הוֹשִׁיעָם, בְּאַהֲבָתוֹ וּבְחֶמְלָתוֹ הוּא גְאָלָם, וַיְנַטְּלֵם וַיְנַשְּׂאֵם כָּל יְמֵי עוֹלָם: וְנֶאֱמַר: מִי אֵל כָּמוֹךָ נֹשֵׂא עָוׂן וְעוֹבֵר עַל פֶּשַׁע לִשְׁאֵרִית נַחֲלָתוֹ, לֹא הֶחֱזִיק לָעַד אַפּוֹ, כִּי חָפֵץ חֶסֶד הוּא: יָשׁוּב יְרַחֲמֵנוּ יִכְבֹּשׁ עֲוׂנוֹתֵינוּ וְתַשְׁלִיךְ בִּמְצֻלוֹת יָם כָּל חַטֹּאתָם: תִּתֵּן אֱמֶת לְיַעֲקֹב, חֶסֶד לְאַבְרָהָם, אֲשֶׁר נִשְׁבַּעְתָּ לַאֲבוֹתֵינוּ מִימֵי קֶדֶם: וְנֶאֱמַר: וַהֲבִיאוֹתִים אֶל הַר קָדְשִׁי, וְשִׂמַּחְתִּים בְּבֵית תְּפִלָּתִי, עוֹלוֹתֵיהֶם וְזִבְחֵיהֶם לְרָצוֹן עַל מִזְבְּחִי, כִּי בֵיתִי בֵּית תְּפִלָּה יִקָּרֵא לְכָל הָעַמִּים:","cond":[]},{"kind":"text","text":"לְעוֹלָם יְהֵא אָדָם יְרֵא שָׁמַיִם בְּסֵתֶר, וּמוֹדֶה עַל הָאֱמֶת, וְדוֹבֵר אֱמֶת בִּלְבָבוֹ, וְיַשְׁכֵּם וְיֹאמַר:\n\nרִבּוֹן כָּל הָעוֹלָמִים, לֹא עַל צִדְקוֹתֵינוּ אֲנַחְנוּ מַפִּילִים תַּחֲנוּנֵינוּ לְפָנֶיךָ, כִּי עַל רַחֲמֶיךָ הָרַבִּים. מָה אָנוּ, מֶה חַיֵּינוּ, מֶה חַסְדֵּנוּ, מַה צִּדְקֵנוּ, מַה יְּשׁוּעָתֵנוּ, מַה כֹּחֵנוּ, מַה גְּבוּרָתֵנוּ. מַה נֹּאמַר לְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, הֲלֹא כָּל הַגִּבּוֹרִים כְּאַיִן לְפָנֶיךָ, וְאַנְשֵׁי הַשֵּׁם כְּלֹא הָיוּ, וַחֲכָמִים כִּבְלִי מַדָּע, וּנְבוֹנִים כִּבְלִי הַשְׂכֵּל, כִּי רוֹב מַעֲשֵׂיהֶם תֹּהוּ, וִימֵי חַיֵּיהֶם הֶבֶל לְפָנֶיךָ, וּמוֹתַר הָאָדָם מִן הַבְּהֵמָה אָיִן, כִּי הַכֹּל הָבֶל: לְבַד הַנְּשָׁמָה הַטְּהוֹרָה, שֶׁהִיא עֲתִידָה לִתֵּן דִּין וְחֶשְׁבּוֹן לִפְנֵי כִסֵּא כְבוֹדֶךָ. וְכָל הַגּוֹיִם כְּאַיִן נֶגְדֶּךָ, שֶׁנֶּאֱמַר: הֵן גּוֹיִם כְּמַר מִדְּלִי, וּכְשַׁחַק מֹאזְנַיִם נֶחְשָׁבוּ, הֵן אִיִּים כַּדַּק יִטֹּל:\n\nאֲבָל אֲנַחְנוּ עַמְּךָ בְּנֵי בְרִיתֶךָ, בְּנֵי אַבְרָהָם אֹהַבְךָ שֶׁנִּשְׁבַּעְתָּ לּוֹ בְּהַר הַמּוֹרִיָּה, זֶרַע יִצְחָק יְחִידוֹ שֶׁנֶּעֱקַד עַל גַּבֵּי הַמִּזְבֵּחַ, עֲדַת יַעֲקֹב בִּנְךָ בְּכוֹרֶךָ, שֶׁמֵּאַהֲבָתְךָ שֶׁאָהַבְתָּ אוֹתוֹ וּמִשִּׂמְחָתְךָ שֶׁשָּׂמַחְתָּ בּוֹ קָרָאתָ אֶת שְׁמוֹ יִשְׂרָאֵל וִישֻׁרוּן.\n\nלְפִיכָךְ אֲנַחְנוּ חַיָּבִים לְהוֹדוֹת לְךָ, וּלְשַׁבֵּחֲךָ וּלְפָאֶרְךָ וּלְבָרֵךְ וּלְקַדֵּשׁ וְלִתֵּן שֶׁבַח וְהוֹדָיָה לִשְׁמֶךָ. אַשְׁרֵינוּ, מַה טּוֹב חֶלְקֵנוּ, וּמַה נָּעִים גּוֹרָלֵנוּ, וּמַה יָּפָה יְרֻשָּׁתֵנוּ, אַשְׁרֵינוּ, שֶׁאָנוּ מַשְׁכִּימִים וּמַעֲרִיבִים בְּבָתֵּי כְנֵסִיּוֹת וּבְבָתֵּי מִדְרָשׁוֹת, וּמְיַחֲדִים שִׁמְךָ בְּכָל יוֹם תָּמִיד וְאוֹמְרִים פַּעֲמַיִם בְּאַהֲבָה:","cond":[]},{"kind":"text","text":"שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:","cond":[]},{"kind":"instruction","text":"בלחש:","cond":[]},{"kind":"text","text":"בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד.\n\nוְאָהַבְתָּ אֵת יהוה אֱלֹהֶיךָ, בְּכָל לְבָבְךָ וּבְכָל נַפְשְׁךָ וּבְכָל מְאֹדֶךָ: וְהָיוּ הַדְּבָרִים הָאֵלֶּה אֲשֶׁר אָנֹכִי מְצַוְּךָ הַיּוֹם, עַל לְבָבֶךָ: וְשִׁנַּנְתָּם לְבָנֶיךָ וְדִבַּרְתָּ בָּם, בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ: וּקְשַׁרְתָּם לְאוֹת עַל יָדֶךָ, וְהָיוּ לְטֹטָפֹת בֵּין עֵינֶיךָ: וּכְתַבְתָּם עַל מְזֻזוֹת בֵּיתֶךָ וּבִשְׁעָרֶיךָ:","cond":[]},{"kind":"text","text":"אַתָּה הוּא עַד שֶׁלֹּא נִבְרָא הָעוֹלָם, אַתָּה הוּא מִשֶּׁנִּבְרָא הָעוֹלָם, אַתָּה הוּא בָּעוֹלָם הַזֶּה, וְאַתָּה הוּא לָעוֹלָם הַבָּא. קַדֵּשׁ אֶת שִׁמְךָ עַל מַקְדִּישֵׁי שְׁמֶךָ, וְקַדֵּשׁ אֶת שִׁמְךָ בְּעוֹלָמֶךָ, וּבִישׁוּעָתְךָ תָּרוּם וְתַגְבִּיהַּ קַרְנֵנוּ לְמַעְלָה, וְהוֹשִׁיעֵנוּ בְּקָרוֹב לְמַעַן שְׁמֶךָ. בָּרוּךְ הַמְקַדֵּשׁ שְׁמוֹ בָּרַבִּים.\n\nאַתָּה הוּא יהוה אֱלֹהֵינוּ בַּשָּׁמַיִם וּבָאָרֶץ וּבִשְׁמֵי הַשָּׁמַיִם הָעֶלְיוֹנִים. אֱמֶת, אַתָּה הוּא רִאשׁוֹן וְאַתָּה הוּא אַחֲרוֹן וּמִבַּלְעָדֶיךָ אֵין אֱלֹהִים. קַבֵּץ נְפוּצוֹת קֹוֶיךָ מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ. יַכִּירוּ וְיֵדְעוּ כָּל בָּאֵי עוֹלָם, כִּי אַתָּה הוּא הָאֱלֹהִים לְבַדְּךָ לְכֹל מַמְלְכוֹת הָאָרֶץ. אַתָּה עָשִׂיתָ אֶת הַשָּׁמַיִם וְאֶת הָאָרֶץ, אֶת הַיָּם וְאֶת כָּל אֲשֶׁר בָּם, וּמִי בְּכָל מַעֲשֵׂי יָדֶיךָ בָּעֶלְיוֹנִים וּבַתַּחְתּוֹנִים שֶׁיֹּאמַר לְךָ מַה תַּעֲשֶׂה וּמַה תִּפְעָל. אָבִינוּ שֶׁבַּשָּׁמַיִם חַי וְקַיָּם, עֲשֵׂה עִמָּנוּ צְדָקָה וָחֶסֶד בַּעֲבוּר שִׁמְךָ הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא שֶׁנִּקְרָא עָלֵינוּ, וְקַיֶּם לָנוּ יהוה אֱלֹהֵינוּ אֶת הַדָּבָר שֶׁהִבְטַחְתָּנוּ עַל יְדֵי צְפַנְיָה חוֹזָךְ, כָּאָמוּר: בָּעֵת הַהִיא אָבִיא אֶתְכֶם, וּבָעֵת קַבְּצִי אֶתְכֶם, כִּי אֶתֵּן אֶתְכֶם לְשֵׁם וְלִתְהִלָּה בְּכֹל עַמֵּי הָאָרֶץ, בְּשׁוּבִי אֶת שְׁבוּתֵיכֶם לְעֵינֵיכֶם, אָמַר יהוה:","cond":[]},{"kind":"header","text":"סדר הקרבנות","cond":[]},{"kind":"instruction","text":"סדר הקרבנות","cond":[]},{"kind":"instruction","text":"פרשת הכיור","cond":[]},{"kind":"text","text":"וַיְדַבֵּר יהוה אֶל מֹשֶׁה לֵּאמֹר: וְעָשִׂיתָ כִּיּוֹר נְחֹשֶׁת וְכַנּוֹ נְחֹשֶׁת לְרָחְצָה, וְנָתַתָּ אֹתוֹ בֵּין אֹהֶל מוֹעֵד וּבֵין הַמִּזְבֵּחַ, וְנָתַתָּ שָׁמָּה מָיִם: וְרָחֲצוּ אַהֲרֹן וּבָנָיו מִמֶּנּוּ אֶת יְדֵיהֶם וְאֶת רַגְלֵיהֶם: בְּבֹאָם אֶל אֹהֶל מוֹעֵד יִרְחֲצוּ מַיִם וְלֹא יָמֻתוּ, אוֹ בְגִשְׁתָּם אֶל הַמִּזְבֵּחַ לְשָׁרֵת, לְהַקְטִיר אִשֶּׁה לַיהוה: וְרָחֲצוּ יְדֵיהֶם וְרַגְלֵיהֶם וְלֹא יָמֻתוּ, וְהָיְתָה לָהֶם חָק עוֹלָם, לוֹ וּלְזַרְעוֹ לְדֹרֹתָם:","cond":[]},{"kind":"instruction","text":"פרשת תרומת הדשן","cond":[]},{"kind":"text","text":"וַיְדַבֵּר יהוה אֶל מֹשֶׁה לֵּאמֹר: צַו אֶת אַהֲרֹן וְאֶת בָּנָיו לֵאמֹר, זֹאת תּוֹרַת הָעֹלָה, הִיא הָעֹלָה עַל מוֹקְדָה עַל הַמִּזְבֵּחַ כָּל הַלַּיְלָה עַד הַבֹּקֶר, וְאֵשׁ הַמִּזְבֵּחַ תּוּקַד בּוֹ: וְלָבַשׁ הַכֹּהֵן מִדּוֹ בַד וּמִכְנְסֵי בַד יִלְבַּשׁ עַל בְּשָׂרוֹ, וְהֵרִים אֶת הַדֶּשֶׁן אֲשֶׁר תֹּאכַל הָאֵשׁ, אֶת הָעֹלָה עַל הַמִּזְבֵּחַ, וְשָׂמוֹ אֵצֶל הַמִּזְבֵּחַ: וּפָשַׁט אֶת בְּגָדָיו, וְלָבַשׁ בְּגָדִים אֲחֵרִים, וְהוֹצִיא אֶת הַדֶּשֶׁן אֶל מִחוּץ לַמַּחֲנֶה אֶל מָקוֹם טָהור: וְהָאֵשׁ עַל הַמִּזְבֵּחַ תּוּקַד בּוֹ לֹא תִכְבֶּה, וּבִעֵר עָלֶיהָ הַכֹּהֵן עֵצִים בַּבֹּקֶר בַּבֹּקֶר, וְעָרַךְ עָלֶיהָ הָעֹלָה וְהִקְטִיר עָלֶיהָ חֶלְבֵי הַשְּׁלָמִים: אֵשׁ תָּמִיד תּוּקַד עַל הַמִּזְבֵּחַ לֹא תִכְבֶּה:","cond":[]},{"kind":"instruction","text":"פרשת התמיד","cond":[]},{"kind":"text","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתְּרַחֵם עָלֵינוּ וְתִמְחֹל לָנוּ עַל כָּל חַטֹּאתֵינוּ וּתְכַפֶּר לָנוּ עַל כָּל עֲוׂנוֹתֵינוּ וְתִסְלַח לָנוּ עַל כָּל פְּשָׁעֵינוּ, וְתִבְנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵינוּ, וְנַקְרִיב לְפָנֶיךָ קָרְבַּן הַתָּמִיד שֶׁיְּכַפֵּר בַּעֲדֵנוּ, כְּמוֹ שֶׁכָּתַבְתָּ עָלֵינוּ בְּתוֹרָתֶךָ עַל יְדֵי מֹשֶׁה עַבְדֶּךָ מִפִּי כְבוֹדֶךָ, כָּאָמוּר:\n\nוַיְדַבֵּר יהוה אֶל מֹשֶׁה לֵּאמֹר: צַו אֶת בְּנֵי יִשרָאֵל וְאָמַרְתָּ אֲלֵהֶם, אֶת קָרְבָּנִי לַחְמִי לְאִשַּׁי, רֵיחַ נִיחֹחִי, תִּשְׁמְרוּ לְהַקְרִיב לִי בְּמוֹעֲדוֹ: וְאָמַרְתָּ לָהֶם, זֶה הָאִשֶּׁה אֲשֶׁר תַּקְרִיבוּ לַיהוה, כְּבָשִׂים בְּנֵי שָׁנָה תְמִימִים, שְׁנַיִם לַיּוֹם עֹלָה תָמִיד: אֶת הַכֶּבֶשׂ אֶחָד תַּעֲשֶׂה בַבֹּקֶר, וְאֵת הַכֶּבֶשׂ הַשֵּׁנִי תַּעֲשֶׂה בֵּין הָעַרְבָּיִם: וַעֲשִׂירִית הָאֵיפָה סֹלֶת לְמִנְחָה, בְּלוּלָה בְּשֶׁמֶן כָּתִית רְבִיעִת הַהִין: עֹלַת תָּמִיד, הָעֲשֻׂיָה בְּהַר סִינַי, לְרֵיחַ נִיחֹחַ אִשֶּׁה לַיהוה: וְנִסְכּוֹ רְבִיעִת הַהִין לַכֶּבֶשׂ הָאֶחָד, בַּקֹּדֶשׁ הַסֵּךְ נֶסֶךְ שֵׁכָר לַיהוה: וְאֵת הַכֶּבֶשׂ הַשֵּׁנִי תַּעֲשֶׂה בֵּין הָעַרְבָּיִם, כְּמִנְחַת הַבֹּקֶר וּכְנִסְכּוֹ תַּעֲשֶׂה, אִשֵּׁה רֵיחַ נִיחֹחַ לַיהוה:\n\nוְשָׁחַט אֹתוֹ עַל יֶרֶךְ הַמִּזְבֵּחַ צָפֹנָה לִפְנֵי יהוה, וְזָרְקוּ בְּנֵי אַהֲרֹן הַכֹּהֲנִים אֶת דָּמוֹ עַל הַמִּזְבֵּחַ סָבִיב:\n\nיְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתְּהֵא אֲמִירָה זוֹ חֲשׁוּבָה וּמְקֻבֶּלֶת וּמְרֻצָּה לְפָנֶיךָ כְּאִלּוּ הִקְרַבְנוּ קָרְבַּן הַתָּמִיד בְּמוֹעֲדוֹ וּבִמְקוֹמוֹ וּכְהִלְכָתוֹ:","cond":[]},{"kind":"instruction","text":"פרשת הקטורת","cond":[]},{"kind":"text","text":"אַתָּה הוּא יהוה אֱלֹהֵינוּ שֶׁהִקְטִירוּ אֲבוֹתֵינוּ לְפָנֶיךָ אֶת קְטֹרֶת הַסַּמִּים בִּזְמַן שֶׁבֵּית הַמִּקְדָּשׁ הָיָה קַיָּם, כַּאֲשֶׁר צִוִּיתָ אוֹתָם עַל יַד מֹשֶׁה נְבִיאֶךָ, כַּכָּתוּב בְּתוֹרָתֶךָ: וַיֹּאמֶר יהוה אֶל מֹשֶׁה, קַח לְךָ סַמִּים נָטָף וּשְׁחֵלֶת וְחֶלְבְּנָה סַמִּים וּלְבֹנָה זַכָּה בַּד בְּבַד יִהְיֶה: וְעָשִׂיתָ אֹתָהּ קְטֹרֶת, רֹקַח מַעֲשֶׂה רוֹקֵחַ, מְמֻלָּח טָהוֹר קֹדֶשׁ: וְשָׁחַקְתָּ מִמֶּנָּה הָדֵק, וְנָתַתָּה מִמֶּנָּה לִפְנֵי הָעֵדֻת בְּאֹהֶל מוֹעֵד אֲשֶׁר אִוָּעֵד לְךָ שָׁמָּה, קֹדֶשׁ קָדָשִׁים תִּהְיֶה לָכֶם:\n\nוְנֶאֱמַר: וְהִקְטִיר עָלָיו אַהֲרֹן קְטֹרֶת סַמִּים, בַּבֹּקֶר בַּבֹּקֶר בְּהֵיטִיבוֹ אֶת הַנֵּרוֹת יַקְטִירֶנָּה: וּבְהַעֲלֹת אַהֲרֹן אֶת הַנֵּרֹת בֵּין הָעַרְבַּיִם יַקְטִירֶנָּה, קְטֹרֶת תָּמִיד לִפְנֵי יהוה לְדֹרֹתֵיכֶם:\n\nתָּנוּ רַבָּנָן: פִּטּוּם הַקְּטֹרֶת כֵּיצַד? שְׁלֹשׁ מֵאוֹת וְשִׁשִּׁים וּשְׁמוֹנָה מָנִים הָיוּ בָהּ. שְׁלֹשׁ מֵאוֹת וְשִׁשִּׁים וַחֲמִשָּׁה כְּמִנְיַן יְמוֹת הַחַמָּה, מָנֶה לְכָל יוֹם, פְּרַס בְּשַׁחֲרִית וּפְרַס בֵּין הָעַרְבָּיִם. וּשְׁלֹשָׁה מָנִים יְתֵרִים שֶׁמֵּהֶם מַכְנִיס כֹּהֵן גָּדוֹל מְלֹא חָפְנָיו בְּיוֹם הַכִּפּוּרִים, וּמַחֲזִירָן לְמַכְתֶּשֶׁת בְּעֶרֶב יוֹם הַכִּפּוּרִים, וְשׁוֹחֲקָן יָפֶה יָפֶה כְּדֵי שֶׁתְּהֵא דַקָּה מִן הַדַּקָּה. וְאַחַד עָשָׂר סַמָּנִים הָיוּ בָהּ, וְאֵלּוּ הֵן: (א) הַצֳּרִי (ב) וְהַצִּפֹּרֶן, (ג) הַחֶלְבְּנָה (ד) וְהַלְּבוֹנָה מִשְׁקַל שִׁבְעִים שִׁבְעִים מָנֶה, (ה) מֹר (ו) וּקְצִיעָה, (ז) שִׁבֹּלֶת נֵרְדְּ (ח) וְכַרְכֹּם מִשְׁקַל שִׁשָּׁה עָשָׂר שִׁשָּׁה עָשָׂר מָנֶה, (ט) הַקֹּשְׁטְ שְׁנֵים עָשָׂר, (י) קִלּוּפָה שְׁלֹשָׁה, (יא) קִנָּמוֹן תִּשְׁעָה, בֹּרִית כַּרְשִׁינָה תִּשְׁעָה קַבִּין, יֵין קַפְרִיסִין סְאִין תְּלָתָא וְקַבִּין תְּלָתָא, וְאִם לֹא מָצָא יֵין קַפְרִיסִין מֵבִיא חֲמַר חִוַּרְיָן עַתִּיק. מֶלַח סְדוֹמִית רֹבַע מַעֲלֶה עָשָׁן כָּל שֶׁהוּא. רַבִּי נָתָן הַבַּבְלִי אוֹמֵר: אַף כִּפַּת הַיַּרְדֵּן כָּל שֶׁהוּא. וְאִם נָתַן בָּהּ דְּבַשׁ פְּסָלָהּ, וְאִם חִסַּר אַחַת מִכָּל סַמָּנֶיהָ חַיָּב מִיתָה.\n\nרַבָּן שִׁמְעוֹן בֶּן גַּמְלִיאֵל אוֹמֵר: הַצֳּרִי אֵינוֹ אֶלָּא שְׂרָף הַנּוֹטֵף מֵעֲצֵי הַקְּטָף. בֹּרִית כַּרְשִׁינָה שֶׁשָּׁפִין בָּהּ אֶת הַצִּפֹּרֶן כְּדֵי שֶׁתְּהֵא נָאָה. יֵין קַפְרִיסִין שֶׁשּׁוֹרִין בּוֹ אֶת הַצִּפֹּרֶן כְּדֵי שֶׁתְּהֵא עַזָּה. וַהֲלֹא מֵי רַגְלַיִם יָפִין לָהּ, אֶלָּא שֶׁאֵין מַכְנִיסִין מֵי רַגְלַיִם בַּמִּקְדָּשׁ מִפְּנֵי הַכָּבוֹד.\n\nתַּנְיָא: רַבִּי נָתָן אוֹמֵר: כְּשֶׁהוּא שׁוֹחֵק אוֹמֵר: הָדֵק הֵיטֵב, הֵיטֵב הָדֵק, מִפְּנֵי שֶׁהַקּוֹל יָפֶה לַבְּשָׂמִים. פִּטְּמָהּ לַחֲצָאִין כְּשֵׁרָה. לִשְׁלִישׁ וְלִרְבִיעַ לֹא שָׁמַעְנוּ. אָמַר רַבִּי יְהוּדָה: זֶה הַכְּלָל: אִם כְּמִדָּתָהּ כְּשֵׁרָה לַחֲצָאִין, וְאִם חִסַּר אַחַת מִכָּל סַמָּנֶיהָ חַיָּב מִיתָה.\n\nתַּנְיָא: בַּר קַפָּרָא אוֹמֵר: אַחַת לְשִׁשִּׁים אוֹ לְשִׁבְעִים שָׁנָה הָיְתָה בָאָה שֶׁל שִׁירַיִם לַחֲצָאִין. וְעוֹד תָּנֵי בַּר קַפָּרָא: אִלּוּ הָיָה נוֹתֵן בָּהּ קוֹרְטוֹב שֶׁל דְּבַשׁ אֵין אָדָם יָכוֹל לַעֲמֹד מִפְּנֵי רֵיחָהּ, וְלָמָה אֵין מְעָרְבִין בָּהּ דְּבַשׁ? מִפְּנֵי שֶׁהַתּוֹרָה אָמְרָה: כִּי כָל שְׂאֹר וְכָל דְּבַשׁ לֹא תַקְטִירוּ מִמֶּנּוּ אִשֶּׁה לַיהוה:\n\nיהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה:\nיהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה:\nיהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה:\n\nיהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ:\nיהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ:\nיהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ:\n\nיהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:\nיהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:\nיהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:\n\nאַתָּה סֵתֶר לִי מִצַּר תִּצְּרֵנִי רָנֵּי פַלֵּט תְּסוֹבְבֵנִי סֶלָה: וְעָרְבָה לַיהוה מִנְחַת יְהוּדָה וִירוּשָׁלָיִם כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמוֹנִיּות:","cond":[]},{"kind":"instruction","text":"סדר המערכה","cond":[]},{"kind":"text","text":"אַבַּיֵּי הֲוָה מְסַדֵּר סֵדֶר הַמַּעֲרָכָה מִשְּׁמָא דִּגְמָרָא וְאַלִּבָּא דְאַבָּא שָׁאוּל: מַעֲרָכָה גְדוֹלָה קוֹדֶמֶת לְמַעֲרָכָה שְׁנִיָּה שֶׁל קְטֹרֶת, וּמַעֲרָכָה שְׁנִיָּה שֶׁל קְטֹרֶת קוֹדֶמֶת לְסִדּוּר שְׁנֵי גִזְרֵי עֵצִים, וְסִדּוּר שְׁנֵי גִזְרֵי עֵצִים קוֹדֵם לְדִשּׁוּן מִזְבֵּחַ הַפְּנִימִי, וְדִשּׁוּן מִזְבֵּחַ הַפְּנִימִי קוֹדֵם לַהֲטָבַת חָמֵשׁ נֵרוֹת, וַהֲטָבַת חָמֵשׁ נֵרוֹת קוֹדֶמֶת לְדַם הַתָּמִיד, וְדַם הַתָּמִיד קוֹדֵם לַהֲטָבַת שְׁתֵּי נֵרוֹת, וַהֲטָבַת שְׁתֵּי נֵרוֹת קוֹדֶמֶת לִקְטֹרֶת, וּקְטֹרֶת קוֹדֶמֶת לְאֵבָרִים, וְאֵבָרִים לְמִנְחָה, וּמִנְחָה לַחֲבִתִּין, וַחֲבִתִּין לִנְסָכִין, וּנְסָכִין לְמוּסָפִין, וּמוּסָפִין לְבָזִיכִין, וּבָזִיכִין קוֹדְמִין לְתָמִיד שֶׁל בֵּין הָעַרְבָּיִם, שֶׁנֶּאֱמַר: וְעָרַךְ עָלֶיהָ הָעֹלָה, וְהִקְטִיר עָלֶיהָ חֶלְבֵי הַשְּׁלָמִים: עָלֶיהָ הַשְׁלֵם כָּל הַקָּרְבָּנות כֻּלָּם.","cond":[]},{"kind":"text","text":"אָנָּא, בְּכֹחַ גְּדֻלַּת יְמִינְךָ, תַּתִּיר צְרוּרָה (אב\"ג ית\"ץ).","cond":[]},{"kind":"text","text":"קַבֵּל רִנַּת עַמְּךָ, שַׂגְּבֵנוּ, טַהֲרֵנוּ, נוֹרָא (קר\"ע שט\"ן).","cond":[]},{"kind":"text","text":"נָא גִּבּוֹר, דּוֹרְשֵׁי יִחוּדֶךָ, כְּבָבַת שָׁמְרֵם (נג\"ד יכ\"ש).","cond":[]},{"kind":"text","text":"בָּרְכֵם, טַהֲרֵם, רַחֲמֵי צִדְקָתְךָ תָּמִיד גָּמְלֵם (בט\"ר צת\"ג).","cond":[]},{"kind":"text","text":"חָסִין קָדוֹשׁ, בְּרֹב טוּבְךָ נַהֵל עֲדָתֶךָ (חק\"ב טנ\"ע).","cond":[]},{"kind":"text","text":"יָחִיד גֵּאֶה, לְעַמְּךָ פְנֵה, זוֹכְרֵי קְדֻשָּׁתֶךָ (יג\"ל פז\"ק).","cond":[]},{"kind":"text","text":"שַׁוְעָתֵנוּ קַבֵּל, וּשְׁמַע צַעֲקָתֵנוּ, יוֹדֵעַ תַּעֲלוּמוֹת (שק\"ו צי\"ת).","cond":[]},{"kind":"text","text":"בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֵד.\n\nרִבּוֹן הָעוֹלָמִים, אַתָּה צִוִּיתָנוּ לְהַקְרִיב קָרְבַּן הַתָּמִיד בְּמוֹעֲדוֹ וְלִהְיוֹת כֹּהֲנִים בַּעֲבוֹדָתָם וּלְוִיִּם בְּדוּכָנָם וְיִשְׂרָאֵל בְּמַעֲמָדָם, וְעַתָּה בַּעֲוׂנוֹתֵינוּ חָרַב בֵּית הַמִּקְדָּשׁ וּבָטַל הַתָּמִיד וְאֵין לָנוּ לֹא כֹהֵן בַּעֲבוֹדָתוֹ וְלֹא לֵוִי בְּדוּכָנוֹ וְלֹא יִשְׂרָאֵל בְּמַעֲמָדוֹ, לָכֵן יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁיְּהֵא שִׂיחַ שִׂפְתוֹתֵינוּ חָשׁוּב וּמְקֻבָּל וּמְרֻצֶּה לְפָנֶיךָ כְּאִלּוּ הִקְרַבְנוּ קָרְבַּן הַתָּמִיד בְּמוֹעֲדוֹ וְעָמַדְנוּ עַל מַעֲמָדוֹ.","cond":[]},{"kind":"instruction","text":"פסוקי מוסף ראש חדש","cond":["rh"]},{"kind":"text","text":"וּבְרָאשֵׁי חָדְשֵׁיכֶם תַּקְרִיבוּ עֹלָה לַיהוה, פָּרִים בְּנֵי בָקָר שְׁנַיִם וְאַיִל אֶחָד, כְּבָשִׂים בְּנֵי שָׁנָה שִׁבְעָה, תְּמִימִם: וּשְׁלֹשָׁה עֶשְׂרֹנִים, סֹלֶת מִנְחָה בְּלוּלָה בַשֶּׁמֶן לַפָּר הָאֶחָד, וּשְׁנֵי עֶשְׂרֹנִים סֹלֶת מִנְחָה בְּלוּלָה בַשֶּׁמֶן לָאַיִל הָאֶחָד: וְעִשָּׂרֹן עִשָּׂרוֹן, סֹלֶת מִנְחָה בְּלוּלָה בַשֶּׁמֶן לַכֶּבֶשׂ הָאֶחָד, עֹלָה רֵיחַ נִיחֹחַ אִשֶּׁה לַיהוה: וְנִסְכֵּיהֶם חֲצִי הַהִין יִהְיֶה לַפָּר, וּשְׁלִישִׁת הַהִין לָאַיִל, וּרְבִיעִת הַהִין לַכֶּבֶשׂ יָיִן, זֹאת עֹלַת חֹדֶשׁ בְּחָדְשׁוֹ לְחָדְשֵׁי הַשָּׁנָה: וּשְׂעִיר עִזִּים אֶחָד לְחַטָּאת לַיהוה, עַל עֹלַת הַתָּמִיד יֵעָשֶׂה וְנִסְכּוֹ:","cond":["rh"]},{"kind":"header","text":"איזהו מקומן","cond":[]},{"kind":"instruction","text":"פרק איזהו מקומן","cond":[]},{"kind":"text","text":"אֵיזֶהוּ מְקוֹמָן שֶׁל זְבָחִים: קָדְשֵׁי קָדָשִׁים שְׁחִיטָתָן בַּצָּפוֹן. פָּר וְשָׂעִיר שֶׁל יוֹם הַכִּפּוּרִים שְׁחִיטָתָן בַּצָּפוֹן, וְקִבּוּל דָּמָן בִּכְלִי שָׁרֵת בַּצָּפוֹן, וְדָמָן טָעוּן הַזָּיָה עַל בֵּין הַבַּדִּים וְעַל הַפָּרֹכֶת וְעַל מִזְבַּח הַזָּהָב, מַתָּנָה אַחַת מֵהֶן מְעַכָּבֶת. שְׁיָרֵי הַדָּם הָיָה שׁוֹפֵךְ עַל יְסוֹד מַעֲרָבִי שֶׁל מִזְבֵּחַ הַחִיצוֹן, אִם לֹא נָתַן לֹא עִכֵּב.\n\nפָּרִים הַנִּשְׂרָפִים וּשְׂעִירִים הַנִּשְׂרָפִים שְׁחִיטָתָן בַּצָּפוֹן, וְקִבּוּל דָּמָן בִּכְלִי שָׁרֵת בַּצָּפוֹן, וְדָמָן טָעוּן הַזָּיָה עַל הַפָּרֹכֶת וְעַל מִזְבַּח הַזָּהָב, מַתָּנָה אַחַת מֵהֶן מְעַכָּבֶת. שְׁיָרֵי הַדָּם הָיָה שׁוֹפֵךְ עַל יְסוֹד מַעֲרָבִי שֶׁל מִזְבֵּחַ הַחִיצוֹן, אִם לֹא נָתַן לֹא עִכֵּב. אֵלּוּ וָאֵלּוּ נִשְׂרָפִין בְּבֵית הַדָּשֶׁן.\n\nחַטֹּאת הַצִּבּוּר וְהַיָּחִיד, אֵלּוּ הֵן חַטֹּאת הַצִּבּוּר: שְׂעִירֵי רָאשֵׁי חֳדָשִׁים וְשֶׁל מוֹעֲדוֹת, שְׁחִיטָתָן בַּצָּפוֹן, וְקִבּוּל דָּמָן בִּכְלִי שָׁרֵת בַּצָּפוֹן, וְדָמָן טָעוּן אַרְבַּע מַתָּנוֹת עַל אַרְבַּע קְרָנוֹת. כֵּיצַד? עָלָה בַכֶּבֶשׁ, וּפָנָה לַסּוֹבֵב, וּבָא לוֹ לְקֶרֶן דְּרוֹמִית מִזְרָחִית, מִזְרָחִית צְפוֹנִית, צְפוֹנִית מַעֲרָבִית, מַעֲרָבִית דְּרוֹמִית. שְׁיָרֵי הַדָּם הָיָה שׁוֹפֵךְ עַל יְסוֹד דְּרוֹמִי, וְנֶאֱכָלִין לִפְנִים מִן הַקְּלָעִים, לְזִכְרֵי כְהֻנָּה, בְּכָל מַאֲכָל, לְיוֹם וָלַיְלָה עַד חֲצוֹת.\n\nהָעוֹלָה קֹדֶשׁ קָדָשִׁים, שְׁחִיטָתָהּ בַּצָּפוֹן, וְקִבּוּל דָּמָהּ בִּכְלִי שָׁרֵת בַּצָּפוֹן, וְדָמָהּ טָעוּן שְׁתֵּי מַתָּנוֹת שֶׁהֵן אַרְבַּע, וּטְעוּנָה הֶפְשֵׁט וְנִתּוּחַ וְכָלִיל לָאִשִּׁים.\n\nזִבְחֵי שַׁלְמֵי צִבּוּר וַאֲשָׁמוֹת, אֵלּוּ הֵן אֲשָׁמוֹת: אֲשַׁם גְּזֵלוֹת, אֲשַׁם מְעִילוֹת, אֲשַׁם שִׁפְחָה חֲרוּפָה, אֲשַׁם נָזִיר, אֲשַׁם מְצֹרָע, אָשָׁם תָּלוּי, שְׁחִיטָתָן בַּצָּפוֹן, וְקִבּוּל דָּמָן בִּכְלִי שָׁרֵת בַּצָּפוֹן, וְדָמָן טָעוּן שְׁתֵּי מַתָּנוֹת שֶׁהֵן אַרְבַּע, וְנֶאֱכָלִין לִפְנִים מִן הַקְּלָעִים, לְזִכְרֵי כְהֻנָּה, בְּכָל מַאֲכָל, לְיוֹם וָלַיְלָה עַד חֲצוֹת.\n\nהַתּוֹדָה וְאֵיל נָזִיר קָדָשִׁים קַלִּים, שְׁחִיטָתָן בְּכָל מָקוֹם בָּעֲזָרָה, וְדָמָן טָעוּן שְׁתֵּי מַתָּנוֹת שֶׁהֵן אַרְבַּע, וְנֶאֱכָלִין בְּכָל הָעִיר, לְכָל אָדָם, בְּכָל מַאֲכָל, לְיוֹם וָלַיְלָה עַד חֲצוֹת. הַמּוּרָם מֵהֶם כַּיּוֹצֵא בָהֶם, אֶלָּא שֶׁהַמּוּרָם נֶאֱכָל לַכֹּהֲנִים לִנְשֵׁיהֶם וְלִבְנֵיהֶם וּלְעַבְדֵיהֶם.\n\nשְׁלָמִים קָדָשִׁים קַלִּים, שְׁחִיטָתָן בְּכָל מָקום בָּעֲזָרָה, וְדָמָן טָעוּן שְׁתֵּי מַתָּנוֹת שֶׁהֵן אַרְבַּע, וְנֶאֱכָלִין בְּכָל הָעִיר, לְכָל אָדָם, בְּכָל מַאֲכָל, לִשְׁנֵי יָמִים וְלַיְלָה אֶחָד. הַמּוּרָם מֵהֶם כַּיּוֹצֵא בָהֶם, אֶלָּא שֶׁהַמּוּרָם נֶאֱכָל לַכֹּהֲנִים לִנְשֵׁיהֶם וְלִבְנֵיהֶם וּלְעַבְדֵיהֶם.\n\nהַבְּכוֹר וְהַמַּעֲשֵׂר וְהַפֶּסַח קָדָשִׁים קַלִּים, שְׁחִיטָתָן בְּכָל מָקוֹם בָּעֲזָרָה, וְדָמָן טָעוּן מַתָּנָה אֶחָת, וּבִלְבָד שֶׁיִּתֵּן כְּנֶגֶד הַיְסוֹד. שִׁנָּה בַאֲכִילָתָן: הַבְּכוֹר נֶאֱכָל לַכֹּהֲנִים, וְהַמַּעֲשֵׂר לְכָל אָדָם. וְנֶאֱכָלִין בְּכָל הָעִיר, בְּכָל מַאֲכָל, לִשְׁנֵי יָמִים וְלַיְלָה אֶחָד. הַפֶּסַח אֵינוֹ נֶאֱכָל אֶלָּא בַלַּיְלָה, וְאֵינוֹ נֶאֱכָל אֶלָּא עַד חֲצוֹת, וְאֵינוֹ נֶאֱכָל אֶלָּא לִמְנוּיָיו, וְאֵינוֹ נֶאֱכָל אֶלָּא צָלִי.","cond":[]},{"kind":"header","text":"ברייתא דרבי ישמעאל","cond":[]},{"kind":"instruction","text":"ברייתא דרבי ישמעאל","cond":[]},{"kind":"text","text":"רַבִּי יִשְׁמָעֵאל אוֹמֵר: בִּשְׁלֹשׁ עֶשְׂרֵה מִדּוֹת הַתּוֹרָה נִדְרֶשֶׁת בָּהֵן: מִקַּל וָחֹמֶר, וּמִגְּזֵרָה שָׁוָה, מִבִּנְיַן אָב מִכָּתוּב אֶחָד וּמִבִּנְיַן אָב מִשְּׁנֵי כְתוּבִים, מִכְּלָל וּפְרָט, וּמִפְּרָט וּכְלָל, כְּלָל וּפְרָט וּכְלָל אִי אַתָּה דָן אֶלָּא כְּעֵין הַפְּרָט, מִכְּלָל שֶׁהוּא צָרִיךְ לִפְרָט, וּמִפְּרָט שֶׁהוּא צָרִיךְ לִכְלָל, כָּל דָּבָר שֶׁהָיָה בִּכְלָל וְיָצָא מִן הַכְּלָל לְלַמֵּד לֹא לְלַמֵּד עַל עַצְמוֹ יָצָא אֶלָּא לְלַמֵּד עַל הַכְּלָל כֻּלּוֹ יָצָא, כָּל דָּבָר שֶׁהָיָה בִּכְלָל וְיָצָא לִטְעוֹן טֹעַן אֶחָד שֶׁהוּא כְעִנְיָנוֹ יָצָא לְהָקֵל וְלֹא לְהַחֲמִיר, כָּל דָּבָר שֶׁהָיָה בִּכְלָל וְיָצָא לִטְעוֹן טֹעַן אַחֵר שֶׁלֹּא כְעִנְיָנוֹ יָצָא לְהָקֵל וּלְהַחֲמִיר, כָּל דָּבָר שֶׁהָיָה בִּכְלָל וְיָצָא לִדּוֹן בְּדָבָר הֶחָדָשׁ אִי אַתָּה יָכוֹל לְהַחֲזִירוֹ לִכְלָלוֹ עַד שֶׁיַּחֲזִירֶנּוּ הַכָּתוּב לִכְלָלוֹ בְּפֵרוּשׁ, דָּבָר הַלָּמֵד מֵעִנְיָנוֹ וְדָבָר הַלָּמֵד מִסּוֹפוֹ, וְכֵן שְׁנֵי כְתוּבִים הַמַּכְחִישִׁים זֶה אֶת זֶה עַד שֶׁיָּבוֹא הַכָּתוּב הַשְּׁלִישִׁי וְיַכְרִיעַ בֵּינֵיהֶם.\n\nיְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁיִּבָּנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵינוּ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתֶךָ, וְשָׁם נַעֲבָדְךָ בְּיִרְאָה כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמוֹנִיּוֹת.","cond":[]},{"kind":"instruction","text":"קדיש דרבנן","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":[]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"עַל יִשְׂרָאֵל וְעַל רַבָּנָן וְעַל תַּלְמִידֵיהוֹן וְעַל כָּל תַּלְמִידֵי תַלְמִידֵיהוֹן וְעַל כָּל מָאן דְּעָסְקִין בְּאוֹרַיְתָא דִּי בְאַתְרָא (קַדִּישָׁא) הָדֵין וְדִי בְכָל אָתָר וְאָתָר, יְהֵא לְהוֹן וּלְכוֹן שְׁלָמָא רַבָּא חִנָּא וְחִסְדָּא וְרַחֲמֵי וְחַיֵּי אֲרִיכֵי וּמְזוֹנֵי רְוִיחֵי וּפֻרְקָנָא מִן קֳדָם אֲבוּהוֹן דִּי בִשְׁמַיָּא וְאַרְעָא וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"header","text":"פסוקי דזמרה","cond":[]},{"kind":"instruction","text":"פסוקי דזמרה","cond":[]},{"kind":"text","text":"הוֹדוּ לַיהוה קִרְאוֹ בִשְׁמוֹ, הוֹדִיעוּ בָעַמִּים עֲלִילוֹתָיו: שִׁירוּ לוֹ זַמְּרוּ לוֹ, שִׂיחוּ בְּכָל נִפְלְאוֹתָיו: הִתְהַלְלוּ בְּשֵׁם קָדְשׁוֹ, יִשְׂמַח לֵב מְבַקְשֵׁי יהוה: דִּרְשׁוּ יהוה וְעֻזּוֹ, בַּקְּשׁוּ פָנָיו תָּמִיד: זִכְרוּ נִפְלְאוֹתָיו אֲשֶׁר עָשָׂה, מֹפְתָיו וּמִשְׁפְּטֵי פִיהוּ: זֶרַע יִשְׂרָאֵל עַבְדּוֹ, בְּנֵי יַעֲקֹב בְּחִירָיו: הוּא יהוה אֱלֹהֵינוּ בְּכָל הָאָרֶץ מִשְׁפָּטָיו: זִכְרוּ לְעוֹלָם בְּרִיתוֹ, דָּבָר צִוָּה לְאֶלֶף דּוֹר: אֲשֶׁר כָּרַת אֶת אַבְרָהָם, וּשְׁבוּעָתוֹ לְיִצְחָק: וַיַּעֲמִידֶהָ לְיַעֲקֹב לְחֹק, לְיִשְׂרָאֵל בְּרִית עוֹלָם: לֵאמֹר, לְךָ אֶתֵּן אֶרֶץ כְּנָעַן, חֶבֶל נַחֲלַתְכֶם: בִּהְיוֹתְכֶם מְתֵי מִסְפָּר, כִּמְעַט וְגָרִים בָּהּ: וַיִּתְהַלְּכוּ מִגּוֹי אֶל גּוֹי וּמִמַּמְלָכָה אֶל עַם אַחֵר: לֹא הִנִּיחַ לְאִישׁ לְעָשְׁקָם, וַיּוֹכַח עֲלֵיהֶם מְלָכִים: אַל תִּגְּעוּ בִּמְשִׁיחָי, וּבִנְבִיאַי אַל תָּרֵעוּ: שִׁירוּ לַיהוה כָּל הָאָרֶץ, בַּשְּׂרוּ מִיּוֹם אֶל יוֹם יְשׁוּעָתוֹ: סַפְּרוּ בַגּוֹיִם אֶת כְּבוֹדוֹ, בְּכָל הָעַמִּים נִפְלְאֹתָיו: כִּי גָדוֹל יהוה וּמְהֻלָּל מְאֹד, וְנוֹרָא הוּא עַל כָּל אֱלֹהִים: כִּי כָּל אֱלֹהֵי הָעַמִּים אֱלִילִים, וַיהוה שָׁמַיִם עָשָׂה: הוֹד וְהָדָר לְפָנָיו, עֹז וְחֶדְוָה בִּמְקֹמוֹ: הָבוּ לַיהוה מִשְׁפְּחוֹת עַמִּים, הָבוּ לַיהוה כָּבוֹד וָעֹז: הָבוּ לַיהוה כְּבוֹד שְׁמוֹ, שְׂאוּ מִנְחָה וּבֹאוּ לְפָנָיו, הִשְׁתַּחֲווּ לַיהוה בְּהַדְרַת קֹדֶשׁ: חִילוּ מִלְּפָנָיו כָּל הָאָרֶץ, אַף תִּכּוֹן תֵּבֵל בַּל תִּמּוֹט: יִשְׂמְחוּ הַשָּׁמַיִם וְתָגֵל הָאָרֶץ, וְיֹאמְרוּ בַגּוֹיִם יהוה מָלָךְ: יִרְעַם הַיָּם וּמְלוֹאוֹ, יַעֲלֹץ הַשָּׂדֶה וְכָל אֲשֶׁר בּוֹ: אָז יְרַנְּנוּ עֲצֵי הַיָּעַר מִלִּפְנֵי יהוה, כִּי בָא לִשְׁפּוֹט אֶת הָאָרֶץ: הוֹדוּ לַיהוה כִּי טוֹב, כִּי לְעוֹלָם חַסְדּוֹ: וְאִמְרוּ, הוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ וְקַבְּצֵנוּ וְהַצִּילֵנוּ מִן הַגּוֹיִם, לְהֹדוֹת לְשֵׁם קָדְשֶׁךָ, לְהִשְׁתַּבֵּחַ בִּתְהִלָּתֶךָ: בָּרוּךְ יהוה אֱלֹהֵי יִשְׂרָאֵל מִן הָעוֹלָם וְעַד הָעֹלָם, וַיֹּאמְרוּ כָל הָעָם אָמֵן וְהַלֵּל לַיהוה: רוֹמְמוּ יהוה אֱלֹהֵינוּ וְהִשְׁתַּחֲווּ לַהֲדֹם רַגְלָיו, קָדוֹשׁ הוּא: רוֹמְמוּ יהוה אֱלֹהֵינוּ וְהִשְׁתַּחֲווּ לְהַר קָדְשׁוֹ, כִּי קָדוֹשׁ יהוה אֱלֹהֵינוּ: וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית, וְהִרְבָּה לְהָשִׁיב אַפּוֹ וְלֹא יָעִיר כָּל חֲמָתוֹ: אַתָּה יהוה לֹא תִכְלָא רַחֲמֶיךָ מִמֶּנִּי, חַסְדְּךָ וַאֲמִתְּךָ תָּמִיד יִצְּרוּנִי: זְכֹר רַחֲמֶיךָ יהוה, וַחֲסָדֶיךָ, כִּי מֵעוֹלָם הֵמָּה: תְּנוּ עֹז לֵאלֹהִים, עַל יִשְׂרָאֵל גַּאֲוָתוֹ וְעֻזּוֹ בַּשְּׁחָקִים: נוֹרָא אֱלֹהִים מִמִּקְדָּשֶׁיךָ אֵל יִשְׂרָאֵל, הוּא נֹתֵן עֹז וְתַעֲצֻמוֹת לָעָם, בָּרוּךְ אֱלֹהִים: אֵל נְקָמוֹת יהוה, אֵל נְקָמוֹת הוֹפִיעַ: הִנָּשֵׂא שֹׁפֵט הָאָרֶץ, הָשֵׁב גְּמוּל עַל גֵּאִים: לַיהוה הַיְשׁוּעָה עַל עַמְּךָ בִרְכָתֶךָ, סֶּלָה: יהוה צְבָאוֹת עִמָּנוּ מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב, סֶלָה: יהוה צְבָאוֹת אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ: הוֹשִׁיעָה אֶת עַמֶּךָ וּבָרֵךְ אֶת נַחֲלָתֶךָ, וּרְעֵם וְנַשְּׂאֵם עַד הָעוֹלָם: נַפְשֵׁנוּ חִכְּתָה לַיהוה, עֶזְרֵנוּ וּמָגִנֵּנוּ הוּא: כִּי בוֹ יִשְׂמַח לִבֵּנוּ כִּי בְשֵׁם קָדְשׁוֹ בָטָחְנוּ: יְהִי חַסְדְּךָ יהוה עָלֵינוּ כַּאֲשֶׁר יִחַלְנוּ לָךְ: הַרְאֵנוּ יהוה חַסְדֶּךָ, וְיֶשְׁעֲךָ תִּתֶּן לָנוּ: קוּמָה עֶזְרָתָה לָּנוּ וּפְדֵנוּ לְמַעַן חַסְדֶּךָ: אָנֹכִי יהוה אֱלֹהֶיךָ הַמַּעַלְךָ מֵאֶרֶץ מִצְרָיִם, הַרְחֶב פִּיךָ וַאֲמַלְאֵהוּ: אַשְׁרֵי הָעָם שֶׁכָּכָה לוֹ, אַשְׁרֵי הָעָם שֶׁיהוה אֱלֹהָיו: וַאֲנִי בְּחַסְדְּךָ בָטַחְתִּי, יָגֵל לִבִּי בִּישׁוּעָתֶךָ, אָשִׁירָה לַיהוה כִּי גָמַל עָלָי:","cond":[]},{"kind":"text","text":"מִזְמוֹר שִׁיר חֲנֻכַּת הַבַּיִת לְדָוִד: אֲרוֹמִמְךָ יהוה כִּי דִלִּיתָנִי, וְלֹא שִׂמַּחְתָּ אֹיְבַי לִי: יהוה אֱלֹהָי שִׁוַּעְתִּי אֵלֶיךָ וַתִּרְפָּאֵנִי: יהוה, הֶעֱלִיתָ מִן שְׁאוֹל נַפְשִׁי, חִיִּיתַנִי מִיָּרְדִי בוֹר: זַמְּרוּ לַיהוה חֲסִידָיו וְהוֹדוּ לְזֵכֶר קָדְשׁוֹ: כִּי רֶגַע בְּאַפּוֹ חַיִּים בִּרְצוֹנוֹ, בָּעֶרֶב יָלִין בֶּכִי וְלַבֹּקֶר רִנָּה: וַאֲנִי אָמַרְתִּי בְשַׁלְוִי בַּל אֶמּוֹט לְעוֹלָם: יהוה בִּרְצוֹנְךָ הֶעֱמַדְתָּה לְהַרְרִי עֹז, הִסְתַּרְתָּ פָנֶיךָ הָיִיתִי נִבְהָל: אֵלֶיךָ יהוה אֶקְרָא וְאֶל אֲדֹנָי אֶתְחַנָּן: מַה בֶּצַע בְּדָמִי בְּרִדְתִּי אֶל שָׁחַת, הֲיוֹדְךָ עָפָר הֲיַגִּיד אֲמִתֶּךָ: שְׁמַע יהוה וְחָנֵּנִי, יהוה הֱיֵה עֹזֵר לִי: הָפַכְתָּ מִסְפְּדִי לְמָחוֹל לִי, פִּתַּחְתָּ שַׂקִּי וַתְּאַזְּרֵנִי שִׂמְחָה: לְמַעַן יְזַמֶּרְךָ כָבוֹד וְלֹא יִדֹּם, יהוה אֱלֹהַי לְעוֹלָם אוֹדֶךָּ:","cond":[]},{"kind":"text","text":"יהוה מֶלֶךְ, יהוה מָלָךְ, יהוה יִמְלֹך לְעֹלָם וָעֵד.\nיהוה מֶלֶךְ, יהוה מָלָךְ, יהוה יִמְלֹך לְעֹלָם וָעֵד.\nוְהָיָה יהוה לְמֶלֶךְ עַל כָּל הָאָרֶץ, בַּיּוֹם הַהוּא יִהְיֶה יהוה אֶחָד וּשְׁמוֹ אֶחָד:\n\nהוֹשִׁיעֵנוּ יהוה אֱלֹהֵינוּ וְקַבְּצֵנוּ מִן הַגּוֹיִם, לְהוֹדוֹת לְשֵׁם קָדְשֶׁךָ לְהִשְׁתַּבֵּחַ בִּתְהִלָּתֶךָ: בָּרוּךְ יהוה אֱלֹהֵי יִשְׂרָאֵל מִן הָעוֹלָם וְעַד הָעוֹלָם, וְאָמַר כָּל הָעָם אָמֵן, הַלְלוּיָהּ: כֹּל הַנְּשָׁמָה תְּהַלֵּל יָהּ, הַלְלוּיָהּ:","cond":[]},{"kind":"text","text":"לַמְנַצֵּחַ מִזְמוֹר לְדָוִד: הַשָּׁמַיִם מְסַפְּרִים כְּבוֹד אֵל, וּמַעֲשה יָדָיו מַגִּיד הָרָקִיעַ: יוֹם לְיוֹם יַבִּיעַ אֹמֶר, וְלַיְלָה לְלַיְלָה יְחַוֶּה דָּעַת: אֵין אֹמֶר וְאֵין דְּבָרִים, בְּלִי נִשְׁמָע קוֹלָם: בְּכָל הָאָרֶץ יָצָא קַוָּם, וּבִקְצֵה תֵבֵל מִלֵּיהֶם, לַשֶּׁמֶשׁ שָׂם אֹהֶל בָּהֶם: וְהוּא כְּחָתָן יֹצֵא מֵחֻפָּתוֹ, יָשִׂישׂ כְּגִבּוֹר לָרוּץ אֹרַח: מִקְצֵה הַשָּׁמַיִם מוֹצָאוֹ וּתְקוּפָתוֹ עַל קְצוֹתָם, וְאֵין נִסְתָּר מֵחַמָּתוֹ: תּוֹרַת יהוה תְּמִימָה מְשִׁיבַת נָפֶשׁ, עֵדוּת יהוה נֶאֱמָנָה מַחְכִּימַת פֶּתִי: פִּקּוּדֵי יהוה יְשָׁרִים מְשַׂמְּחֵי לֵב, מִצְוַת יהוה בָּרָה מְאִירַת עֵינָיִם: יִרְאַת יהוה טְהוֹרָה עומֶדֶת לָעַד, מִשְׁפְּטֵי יהוה אֱמֶת צָדְקוּ יַחְדָּו: הַנֶחֱמָדִים מִזָּהָב וּמִפָּז רָב, וּמְתוּקִים מִדְּבַשׁ וְנֹפֶת צוּפִים: גַּם עַבְדְּךָ נִזְהָר בָּהֶם, בְּשָׁמְרָם עֵקֶב רָב: שְׁגִיאות מִי יָבִין מִנִּסְתָּרוֹת נַקֵּנִי: גַּם מִזֵּדִים חֲשֹׂךְ עַבְדֶּךָ, אַל יִמְשְׁלוּ בִי אָז אֵיתָם, וְנִקֵּיתִי מִפֶּשַׁע רָב: יִהְיוּ לְרָצון אִמְרֵי פִי וְהֶגְיון לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגֹאֲלִי:\n\nרַנְּנוּ צַדִּיקִים בַּיהוה, לַיְשָׁרִים נָאוָה תְהִלָּה: הוֹדוּ לַיהוה בְּכִנּוֹר, בְּנֵבֶל עָשׂוֹר זַמְּרוּ לוֹ: שִׁירוּ לוֹ שִׁיר חָדָשׁ, הֵיטִיבוּ נַגֵּן בִּתְרוּעָה: כִּי יָשָׁר דְּבַר יהוה, וְכָל מַעֲשֵׂהוּ בֶּאֱמוּנָה: אֹהֵב צְדָקָה וּמִשְׁפָּט, חֶסֶד יהוה מָלְאָה הָאָרֶץ: בִּדְבַר יהוה שָׁמַיִם נַעֲשׂוּ, וּבְרוּחַ פִּיו כָּל צְבָאָם: כֹּנֵס כַּנֵּד מֵי הַיָּם, נֹתֵן בְּאוֹצָרוֹת תְּהוֹמוֹת: יִירְאוּ מֵיהוה כָּל הָאָרֶץ, מִמֶּנּוּ יָגוּרוּ כָּל יֹשְׁבֵי תֵבֵל: כִּי הוּא אָמַר וַיֶּהִי, הוּא צִוָּה וַיַּעֲמֹד: יהוה הֵפִיר עֲצַת גּוֹיִם, הֵנִיא מַחְשְׁבוֹת עַמִּים: עֲצַת יהוה לְעוֹלָם תַּעֲמֹד, מַחְשְׁבוֹת לִבּוֹ לְדֹר וָדֹר: אַשְׁרֵי הַגּוֹי אֲשֶׁר יהוה אֱלֹהָיו, הָעָם בָּחַר לְנַחֲלָה לוֹ: מִשָּׁמַיִם הִבִּיט יהוה, רָאָה אֶת כָּל בְּנֵי הָאָדָם: מִמְּכוֹן שִׁבְתּוֹ הִשְׁגִּיחַ אֶל כָּל יֹשְׁבֵי הָאָרֶץ: הַיּוֹצֵר יַחַד לִבָּם, הַמֵּבִין אֶל כָּל מַעֲשֵׂיהֶם: אֵין הַמֶּלֶךְ נוֹשָׁע בְּרָב חָיִל, גִּבּוֹר לא יִנָּצֵל בְּרָב כֹּחַ: שֶׁקֶר הַסּוּס לִתְשׁוּעָה, וּבְרֹב חֵילוֹ לֹא יְמַלֵּט: הִנֵּה עֵין יהוה אֶל יְרֵאָיו, לַמְיַחֲלִים לְחַסְדּוֹ: לְהַצִּיל מִמָּוֶת נַפְשָׁם, וּלְחַיּוֹתָם בָּרָעָב: נַפְשֵׁנוּ חִכְּתָה לַיהוה, עֶזְרֵנוּ וּמָגִנֵּנוּ הוּא: כִּי בוֹ יִשְׂמַח לִבֵּנוּ, כִּי בְשֵׁם קָדְשׁו בָטָחְנוּ: יְהִי חַסְדְּךָ יהוה עָלֵינוּ, כַּאֲשֶׁר יִחַלְנוּ לָךְ:\n\nלְדָוִד בְּשַׁנּוֹתו אֶת טַעְמוֹ לִפְנֵי אֲבִימֶלֶךְ, וַיְגָרְשֵׁהוּ וַיֵּלַךְ: אֲבָרְכָה אֶת יהוה בְּכָל עֵת, תָּמִיד תְּהִלָּתוֹ בְּפִי: בַּיהוה תִּתְהַלֵּל נַפְשִׁי, יִשְׁמְעוּ עֲנָוִים וְיִשמָחוּ: גַדְּלוּ לַיהוה אִתִּי, וּנְרוֹמְמָה שְׁמוֹ יַחְדָּו: דָּרַשְׁתִּי אֶת יהוה וְעָנָנִי, וּמִכָּל מְגוּרוֹתַי הִצִּילָנִי: הִבִּיטוּ אֵלָיו וְנָהָרוּ, וּפְנֵיהֶם אַל יֶחְפָּרוּ: זֶה עָנִי קָרָא וַיהוה שָׁמֵעַ, וּמִכָּל צָרוֹתָיו הוֹשִׁיעוֹ: חוֹנֶה מַלְאַךְ יהוה סָבִיב לִירֵאָיו וַיְחַלְּצֵם: טַעֲמוּ וּרְאוּ כִּי טוֹב יהוה, אַשְׁרֵי הַגֶּבֶר יֶחֱסֶה בּוֹ: יְראוּ אֶת יהוה קְדוֹשָׁיו, כִּי אֵין מַחְסוֹר לִירֵאָיו: כְּפִירִים רָשׁוּ וְרָעֵבוּ, וְדוֹרְשֵׁי יהוה לֹא יַחְסְרוּ כָל טוֹב: לְכוּ בָנִים שִׁמְעוּ לִי, יִרְאַת יהוה אֲלַמֶּדְכֶם: מִי הָאִישׁ הֶחָפֵץ חַיִּים, אֹהֵב יָמִים לִרְאוֹת טוֹב: נְצֹר לְשׁוֹנְךָ מֵרָע, וּשפָתֶיךָ מִדַּבֵּר מִרְמָה: סוּר מֵרָע וַעֲשֵׂה טוֹב, בַּקֵּשׁ שָׁלוֹם וְרָדְפֵהוּ: עֵינֵי יהוה אֶל צַדִּיקִים, וְאָזְנָיו אֶל שַׁוְעָתָם: פְּנֵי יהוה בְּעֹשֵׂי רָע, לְהַכְרִית מֵאֶרֶץ זִכְרָם: צָעֲקוּ וַיהוה שָׁמֵעַ, וּמִכָּל צָרוֹתָם הִצִּילָם: קָרוֹב יהוה לְנִשְׁבְּרֵי לֵב, וְאֶת דַּכְּאֵי רוּחַ יוֹשִׁיעַ: רַבּוֹת רָעוֹת צַדִּיק, וּמִכֻּלָּם יַצִּילֶנּוּ יהוה: שֹׁמֵר כָּל עַצְמוֹתָיו, אַחַת מֵהֵנָּה לֹא נִשְׁבָּרָה: תְּמוֹתֵת רָשָׁע רָעָה, וְשֹׂנְאֵי צַדִּיק יֶאְשָׁמוּ: פּוֹדֶה יהוה נֶפֶשׁ עֲבָדָיו, וְלא יֶאְשְׁמוּ כָּל הַחוֹסִים בּוֹ:\n\nתְּפִלָּה לְמֹשֶׁה אִישׁ הָאֱלֹהִים, אֲדֹנָי מָעוֹן אַתָּה הָיִיתָ לָּנוּ, בְּדוֹר וָדֹר: בְּטֶרֶם הָרִים יֻלָּדוּ וַתְּחוֹלֵל אֶרֶץ וְתֵבֵל, וּמֵעוֹלָם עַד עוֹלָם אַתָּה אֵל: תָּשֵׁב אֱנוֹשׁ עַד דַּכָּא, וַתֹּאמֶר שׁוּבוּ בְנֵי אָדָם: כִּי אֶלֶף שָׁנִים בְּעֵינֶיךָ כְּיוֹם אֶתְמול כִּי יַעֲבֹר, וְאַשְׁמוּרָה בַלָּיְלָה: זְרַמְתָּם שֵׁנָה יִהְיוּ, בַּבֹּקֶר כֶּחָצִיר יַחֲלֹף: בַּבֹּקֶר יָצִיץ וְחָלָף, לָעֶרֶב יְמוֹלֵל וְיָבֵשׁ: כִּי כָלִינוּ בְאַפֶּךָ, וּבַחֲמָתְךָ נִבְהָלְנוּ: שַׁתָּה עֲוׂנוֹתֵינוּ לְנֶגְדֶּךָ, עֲלֻמֵנוּ לִמְאוֹר פָּנֶיךָ: כִּי כָל יָמֵינוּ פָּנוּ בְעֶבְרָתֶךָ, כִּלִּינוּ שָׁנֵינוּ כְּמוֹ הֶגֶה: יְמֵי שְׁנוֹתֵינוּ בָּהֶם שִׁבְעִים שָׁנָה, וְאִם בִּגְבוּרֹת שְׁמוֹנִים שָׁנָה, וְרָהְבָּם עָמָל וָאָוֶן, כִּי גָז חִישׁ וַנָּעֻפָה: מִי יוֹדֵעַ עֹז אַפֶּךָ, וּכְיִרְאָתְךָ עֶבְרָתֶךָ: לִמְנוֹת יָמֵינוּ כֵּן הוֹדַע, וְנָבִיא לְבַב חָכְמָה: שׁוּבָה יהוה עַד מָתָי, וְהִנָּחֵם עַל עֲבָדֶיךָ: שַׂבְּעֵנוּ בַבֹּקֶר חַסְדֶּךָ, וּנְרַנְּנָה וְנִשמְחָה בְּכָל יָמֵינוּ: שַׂמְּחֵנוּ כִּימות עִנִּיתָנוּ, שְׁנוֹת רָאִינוּ רָעָה: יֵרָאֶה אֶל עֲבָדֶיךָ פָעֳלֶךָ, וַהֲדָרְךָ עַל בְּנֵיהֶם: וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ:\n\nיֹשֵׁב בְּסֵתֶר עֶלְיוֹן, בְּצֵל שַׁדַּי יִתְלוֹנָן: אֹמַר לַיהוה מַחְסִי וּמְצוּדָתִי, אֱלֹהַי אֶבְטַח בּוֹ: כִּי הוּא יַצִּילְךָ מִפַּח יָקוּשׁ, מִדֶּבֶר הַוּוֹת: בְּאֶבְרָתו יָסֶךְ לָךְ, וְתַחַת כְּנָפָיו תֶּחְסֶה, צִנָּה וְסוֹחֵרָה אֲמִתּוֹ: לא תִירָא מִפַּחַד לָיְלָה, מֵחֵץ יָעוּף יוֹמָם: מִדֶּבֶר בָּאֹפֶל יַהֲלֹךְ, מִקֶּטֶב יָשׁוּד צָהֳרָיִם: יִפֹּל מִצִּדְּךָ אֶלֶף וּרְבָבָה מִימִינֶךָ, אֵלֶיךָ לֹא יִגָּשׁ: רַק בְּעֵינֶיךָ תַבִּיט, וְשִׁלֻּמַת רְשָׁעִים תִּרְאֶה: כִּי אַתָּה יהוה מַחְסִי, עֶלְיוֹן שמְתָּ מְעוֹנֶךָ: לא תְאֻנֶּה אֵלֶיךָ רָעָה, וְנֶגַע לא יִקְרַב בְּאָהֳלֶךָ: כִּי מַלְאָכָיו יְצַוֶּה לָּךְ, לִשְׁמָרְךָ בְּכָל דְּרָכֶיךָ: עַל כַּפַּיִם יִשָּׂאוּנְךָ, פֶּן תִּגּוֹף בָּאֶבֶן רַגְלֶךָ: עַל שַׁחַל וָפֶתֶן תִּדְרוֹךְ, תִּרְמוֹס כְּפִיר וְתַנִּין: כִּי בִי חָשַׁק וַאֲפַלְּטֵהוּ, אֲשַׂגְּבֵהוּ כִּי יָדַע שְׁמִי: יִקְרָאֵנִי וְאֶעֱנֵהוּ, עִמּוֹ אָנֹכִי בְצָרָה, אֲחַלְּצֵהוּ וַאֲכַבְּדֵהוּ: אֹרֶךְ יָמִים אַשְׂבִּיעֵהוּ, וְאַרְאֵהוּ בִּישׁוּעָתִי: אֹרֶךְ יָמִים אַשְׂבִּיעֵהוּ, וְאַרְאֵהוּ בִּישׁוּעָתִי:\n\nמִזְמוֹר שִׁירוּ לַיהוה שִׁיר חָדָשׁ, כִּי נִפְלָאוֹת עָשָׂה: הוֹשִׁיעָה לּוֹ יְמִינוֹ וּזְרוֹעַ קָדְשׁוֹ: הוֹדִיעַ יהוה יְשׁוּעָתוֹ, לְעֵינֵי הַגּוֹיִם גִּלָּה צִדְקָתוֹ: זָכַר חַסְדּוֹ וֶאֱמוּנָתוֹ לְבֵית יִשְׂרָאֵל, רָאוּ כָל אַפְסֵי אָרֶץ אֵת יְשׁוּעַת אֱלֹהֵינוּ: הָרִיעוּ לַיהוה כָּל הָאָרֶץ, פִּצְחוּ וְרַנְּנוּ וְזַמֵּרוּ: זַמְּרוּ לַיהוה בְּכִנּוֹר, בְּכִנּוֹר וְקוֹל זִמְרָה: בַּחֲצֹצְרוֹת וְקוֹל שׁוֹפָר, הָרִיעוּ לִפְנֵי הַמֶּלֶךְ יהוה: יִרְעַם הַיָּם וּמְלֹאוֹ, תֵּבֵל וְיֹשְׁבֵי בָהּ: נְהָרוֹת יִמְחֲאוּ כָף, יַחַד הָרִים יְרַנֵּנוּ: לִפְנֵי יהוה כִּי בָא לִשְׁפֹּט הָאָרֶץ, יִשְׁפֹּט תֵּבֵל בְּצֶדֶק וְעַמִּים בְּמֵישָׁרִים:\n\nשִׁיר לַמַּעֲלוֹת, אֶשָּׂא עֵינַי אֶל הֶהָרִים, מֵאַיִן יָבֹא עֶזְרִי: עֶזְרִי מֵעִם יהוה, עֹשֵׂה שָׁמַיִם וָאָרֶץ: אַל יִתֵּן לַמּוֹט רַגְלֶךָ, אַל יָנוּם שֹׁמְרֶךָ: הִנֵּה לֹא יָנוּם וְלֹא יִישָׁן שׁוֹמֵר יִשְׂרָאֵל: יהוה שֹׁמְרֶךָ, יהוה צִלְּךָ עַל יַד יְמִינֶךָ: יוֹמָם הַשֶּׁמֶשׁ לֹא יַכֶּכָּה, וְיָרֵחַ בַּלָּיְלָה: יהוה יִשְׁמָרְךָ מִכָּל רָע, יִשְׁמֹר אֶת נַפְשֶׁךָ: יהוה יִשְׁמָר צֵאתְךָ וּבוֹאֶךָ, מֵעַתָּה וְעַד עוֹלָם:\n\nשִׁיר הַמַּעֲלוֹת לְדָוִד, שָׂמַחְתִּי בְּאֹמְרִים לִי בֵּית יהוה נֵלֵךְ: עֹמְדוֹת הָיוּ רַגְלֵינוּ בִּשְׁעָרַיִךְ יְרוּשָׁלָיִם: יְרוּשָׁלַיִם הַבְּנוּיָה, כְּעִיר שֶׁחֻבְּרָה לָהּ יַחְדָּו: שֶׁשָּׁם עָלוּ שְׁבָטִים שִׁבְטֵי יָהּ עֵדוּת לְיִשְׂרָאֵל, לְהוֹדוֹת לְשֵׁם יהוה: כִּי שָׁמָּה יָשְׁבוּ כִסְאוֹת לְמִשְׁפָּט, כִּסְאוֹת לְבֵית דָּוִד: שַׁאֲלוּ שְׁלוֹם יְרוּשָׁלָיִם, יִשְׁלָיוּ אֹהֲבָיִךְ: יְהִי שָׁלוֹם בְּחֵילֵךְ, שַׁלְוָה בְּאַרְמְנֹתָיִךְ: לְמַעַן אַחַי וְרֵעָי, אֲדַבְּרָה נָּא שָׁלוֹם בָּךְ: לְמַעַן בֵּית יהוה אֱלֹהֵינוּ, אֲבַקְשָׁה טוֹב לָךְ:\n\nשִׁיר הַמַּעֲלוֹת, אֵלֶיךָ נָשָׂאתִי אֶת עֵינַי הַיּוֹשְׁבִי בַּשָּׁמָיִם: הִנֵּה כְעֵינֵי עֲבָדִים אֶל יַד אֲדוֹנֵיהֶם, כְּעֵינֵי שִׁפְחָה אֶל יַד גְּבִרְתָּהּ, כֵּן עֵינֵינוּ אֶל יהוה אֱלֹהֵינוּ עַד שֶׁיְּחָנֵּנוּ: חָנֵּנוּ יהוה חָנֵּנוּ, כִּי רַב שָׂבַעְנוּ בוּז: רַבַּת שָׂבְעָה לָּהּ נַפְשֵׁנוּ הַלַּעַג הַשַּׁאֲנַנִּים, הַבּוּז לִגְאֵי יוֹנִים:\n\nשִׁיר הַמַּעֲלוֹת לְדָוִד, לוּלֵי יהוה שֶׁהָיָה לָנוּ יֹאמַר נָא יִשְׂרָאֵל: לוּלֵי יהוה שֶׁהָיָה לָנוּ, בְּקוּם עָלֵינוּ אָדָם: אֲזַי חַיִּים בְּלָעוּנוּ, בַּחֲרוֹת אַפָּם בָּנוּ: אֲזַי הַמַּיִם שְׁטָפוּנוּ, נַחְלָה עָבַר עַל נַפְשֵׁנוּ: אֲזַי עָבַר עַל נַפְשֵׁנוּ, הַמַּיִם הַזֵּידוֹנִים: בָּרוּךְ יהוה, שֶׁלֹּא נְתָנָנוּ טֶרֶף לְשִׁנֵּיהֶם: נַפְשֵׁנוּ כְּצִפּוֹר נִמְלְטָה מִפַּח יוֹקְשִׁים, הַפַּח נִשְׁבָּר וַאֲנַחְנוּ נִמְלָטְנוּ: עֶזְרֵנוּ בְּשֵׁם יהוה, עֹשֵׂה שָׁמַיִם וָאָרֶץ:\n\nהַלְלוּיָהּ, הַלְלוּ אֶת שֵׁם יהוה, הַלְלוּ עַבְדֵי יהוה: שֶׁעוֹמְדִים בְּבֵית יהוה, בְּחַצְרוֹת בֵּית אֱלֹהֵינוּ: הַלְלוּיָהּ כִּי טוֹב יהוה, זַמְּרוּ לִשְׁמוֹ כִּי נָעִים: כִּי יַעֲקֹב בָּחַר לוֹ יָהּ, יִשְׂרָאֵל לִסְגֻלָּתו: כִּי אֲנִי יָדַעְתִּי כִּי גָּדוֹל יהוה, וַאֲדֹנֵינוּ מִכָּל אֱלֹהִים: כֹּל אֲשֶׁר חָפֵץ יהוה עָשָׂה, בַּשָּׁמַיִם וּבָאָרֶץ בַּיַּמִּים וְכָל תְּהֹמֹת: מַעֲלֶה נְשִׂאִים מִקְצֵה הָאָרֶץ, בְּרָקִים לַמָּטָר עָשָׂה, מוֹצֵא רוּחַ מֵאוֹצְרוֹתָיו: שֶׁהִכָּה בְּכוֹרֵי מִצְרָיִם, מֵאָדָם עַד בְּהֵמָה: שָׁלַח אוֹתֹת וּמוֹפְתִים בְּתוֹכֵכִי מִצְרָיִם, בְּפַרְעֹה וּבְכָל עֲבָדָיו: שֶׁהִכָּה גּוֹיִם רַבִּים, וְהָרַג מְלָכִים עֲצוּמִים: לְסִיחוֹן מֶלֶךְ הָאֱמֹרִי וּלְעוֹג מֶלֶךְ הַבָּשָׁן, וּלְכֹל מַמְלְכוֹת כְּנָעַן: וְנָתַן אַרְצָם נַחֲלָה, נַחֲלָה לְיִשְׂרָאֵל עַמּוֹ: יהוה שִׁמְךָ לְעוֹלָם, יהוה זִכְרְךָ לְדֹר וָדֹר: כִּי יָדִין יהוה עַמּוֹ, וְעַל עֲבָדָיו יִתְנֶחָם: עֲצַבֵּי הַגּוֹיִם כֶּסֶף וְזָהָב, מַעֲשֵׂה יְדֵי אָדָם: פֶּה לָהֶם וְלֹא יְדַבֵּרוּ, עֵינַיִם לָהֶם וְלֹא יִרְאוּ: אָזְנַיִם לָהֶם וְלֹא יַאֲזִינוּ, אַף אֵין יֶשׁ רוּחַ בְּפִיהֶם: כְּמוֹהֶם יִהְיוּ עֹשֵׂיהֶם, כֹּל אֲשֶׁר בֹּטֵחַ בָּהֶם: בֵּית יִשְׂרָאֵל בָּרְכוּ אֶת יהוה, בֵּית אַהֲרֹן בָּרְכוּ אֶת יהוה: בֵּית הַלֵּוִי בָּרְכוּ אֶת יהוה, יִרְאֵי יהוה בָּרְכוּ אֶת יהוה: בָּרוּךְ יהוה מִצִּיּוֹן, שֹׁכֵן יְרוּשָׁלָיִם, הַלְלוּיָהּ:\n\nהוֹדוּ ליהוה כִּי טוֹב, כִּי לְעוֹלָם חַסְדּו:\nהוֹדוּ לֵאלֹהֵי הָאֱלֹהִים, כִּי לְעוֹלָם חַסְדּוֹ:\nהוֹדוּ לַאֲדֹנֵי הָאֲדֹנִים, כִּי לְעוֹלָם חַסְדּוֹ:\nלְעֹשֵׂה נִפְלָאוֹת גְּדֹלוֹת לְבַדּוֹ, כִּי לְעוֹלָם חַסְדּוֹ:\nלְעֹשֵׂה הַשָּׁמַיִם בִּתְבוּנָה, כִּי לְעוֹלָם חַסְדּוֹ:\nלְרוֹקַע הָאָרֶץ עַל הַמָּיִם, כִּי לְעוֹלָם חַסְדּוֹ:\nלְעֹשֵׂה אוֹרִים גְּדֹלִים, כִּי לְעוֹלָם חַסְדּוֹ:\nאֶת הַשֶּׁמֶשׁ לְמֶמְשֶׁלֶת בַּיּוֹם, כִּי לְעוֹלָם חַסְדּוֹ:\nאֶת הַיָּרֵחַ וְכוֹכָבִים לְמֶמְשְׁלוֹת בַּלָּיְלָה, כִּי לְעוֹלָם חַסְדּוֹ:\nלְמַכֵּה מִצְרַיִם בִּבְכוֹרֵיהֶם, כִּי לְעוֹלָם חַסְדּוֹ:\nוַיּוֹצֵא יִשְׂרָאֵל מִתּוֹכָם, כִּי לְעוֹלָם חַסְדּוֹ:\nבְּיָד חֲזָקָה וּבִזְרוֹעַ נְטוּיָה, כִּי לְעוֹלָם חַסְדּוֹ:\nלְגֹזֵר יַם סוּף לִגְזָרִים, כִּי לְעוֹלָם חַסְדּוֹ:\nוְהֶעֱבִיר יִשְׂרָאֵל בְּתוֹכוֹ, כִּי לְעוֹלָם חַסְדּוֹ:\nוְנִעֵר פַּרְעֹה וְחֵילוֹ בְיַם סוּף, כִּי לְעוֹלָם חַסְדּוֹ:\nלְמוֹלִיךְ עַמּוֹ בַּמִּדְבָּר, כִּי לְעוֹלָם חַסְדּוֹ:\nלְמַכֵּה מְלָכִים גְּדֹלִים, כִּי לְעוֹלָם חַסְדּוֹ:\nוַיַּהֲרֹג מְלָכִים אַדִּירִים, כִּי לְעוֹלָם חַסְדּוֹ:\nלְסִיחוֹן מֶלֶךְ הָאֱמֹרִי, כִּי לְעוֹלָם חַסְדּוֹ:\nוּלְעוֹג מֶלֶךְ הַבָּשָׁן, כִּי לְעוֹלָם חַסְדּוֹ:\nוְנָתַן אַרְצָם לְנַחֲלָה, כִּי לְעוֹלָם חַסְדּוֹ:\nנַחֲלָה לְיִשְׂרָאֵל עַבְדּוֹ, כִּי לְעוֹלָם חַסְדּוֹ:\nשֶׁבְּשִׁפְלֵנוּ זָכַר לָנוּ, כִּי לְעוֹלָם חַסְדּוֹ:\nוַיִּפְרְקֵנוּ מִצָּרֵינוּ, כִּי לְעוֹלָם חַסְדּוֹ:\nנוֹתֵן לֶחֶם לְכָל בָּשָׂר, כִּי לְעוֹלָם חַסְדּוֹ:\nהוֹדוּ לְאֵל הַשָּׁמָיִם, כִּי לְעוֹלָם חַסְדּוֹ:\n\nהָאַדֶּרֶת וְהָאֱמוּנָה, לְחַי עוֹלָמִים.\nהַבִּינָה וְהַבְּרָכָה, לְחַי עוֹלָמִים.\nהַגַּאֲוָה וְהַגְּדֻלָּה, לְחַי עוֹלָמִים.\nהַדֵּעָה וְהַדִּבּוּר, לְחַי עוֹלָמִים.\nהַהוֹד וְהֶהָדָּר, לְחַי עוֹלָמִים.\nהַוַּעַד וְהַוָּתִיקוּת, לְחַי עוֹלָמִים.\nהַזָּךְ וְהַזֹּהַר, לְחַי עוֹלָמִים.\nהַחַיִל וְהַחֹסֶן, לְחַי עוֹלָמִים.\nהַטֶּכֶס וְהַטֹּהַר, לְחַי עוֹלָמִים.\nהַיִּחוּד וְהַיִּרְאָה, לְחַי עוֹלָמִים.\nהַכֶּתֶר וְהַכָּבוֹד, לְחַי עוֹלָמִים.\nהַלֶּקַח וְהַלִּבּוּב, לְחַי עוֹלָמִים.\nהַמְּלוּכָה וְהַמֶּמְשָׁלָה, לְחַי עוֹלָמִים.\nהַנּוֹי וְהַנֵּצַח, לְחַי עוֹלָמִים.\nהַסִּגּוּי וְהַסֶּגֶּב, לְחַי עוֹלָמִים.\nהָעֹז וְהָעֲנָוָה, לְחַי עוֹלָמִים.\nהַפְּדוּת וְהַפְּאֵר, לְחַי עוֹלָמִים.\nהַצְּבִי וְהַצֶּדֶק, לְחַי עוֹלָמִים.\nהַקְּרִיאָה וְהַקְּדֻשָּׁה, לְחַי עוֹלָמִים.\nהָרֹן וְהָרוֹמֵמוֹת, לְחַי עוֹלָמִים.\nהַשִּׁיר וְהַשֶּׁבַח, לְחַי עוֹלָמִים.\nהַתְּהִלָּה וְהַתִּפְאֶרֶת, לְחַי עוֹלָמִים.","cond":["shabbat"]},{"kind":"header","text":"למנצח","cond":["noShabbat"]},{"kind":"text","text":"לַמְנַצֵּחַ בִּנְגִינֹת מִזְמוֹר שִׁיר: אֱלֹהִים יְחָנֵּנוּ וִיבָרְכֵנוּ, יָאֵר פָּנָיו אִתָּנוּ סֶלָה: לָדַעַת בָּאָרֶץ דַּרְכֶּךָ, בְּכָל-גּוֹיִם יְשׁוּעָתֶךָ: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: יִשְׂמְחוּ וִירַנְּנוּ לְאֻמִּים כִּי-תִשְׁפֹּט עַמִּים מִישֹׁר, וּלְאֻמִּים בָּאָרֶץ תַּנְחֵם סֶלָה: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: אֶרֶץ נָתְנָה יְבוּלָהּ, יְבָרְכֵנוּ אֱלֹהִים אֱלֹהֵינוּ: יְבָרְכֵנוּ אֱלֹהִים, וְיִירְאוּ אוֹתוֹ כָּל-אַפְסֵי-אָרֶץ:","cond":["noShabbat"]},{"kind":"text","text":"הֲרֵינִי מְזַמֵּן אֶת פִּי לְהוֹדוֹת וּלְהַלֵּל וּלְשַׁבֵּחַ אֶת בּוֹרְאִי לְשֵׁם יִחוּד קֻדְשָׁא בְּרִיךְ הוּא וּשְׁכִינְתֵּהּ עַל יְדֵי הַהוּא טָמִיר וְנֶעְלָם בְּשֵׁם כָּל יִשְׂרָאֵל.\n\nבָּרוּךְ שֶׁאָמַר וְהָיָה הָעוֹלָם, בָּרוּךְ הוּא, בָּרוּךְ אוֹמֵר וְעוֹשֶׂה, בָּרוּךְ גּוֹזֵר וּמְקַיֵּם, בָּרוּךְ עוֹשֶׂה בְרֵאשִׁית, בָּרוּךְ מְרַחֵם עַל הָאָרֶץ, בָּרוּךְ מְרַחֵם עַל הַבְּרִיּוֹת, בָּרוּךְ מְשַׁלֵּם שָׂכָר טוֹב לִירֵאָיו, בָּרוּךְ חַי לָעַד וְקַיָּם לָנֶצַח, בָּרוּךְ פּוֹדֶה וּמַצִּיל, בָּרוּךְ שְׁמוֹ. בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הָאֵל אָב הָרַחֲמָן הַמְהֻלָּל בְּפֶה עַמּוֹ, מְשֻׁבָּח וּמְפֹאָר בִּלְשׁוֹן חֲסִידָיו וַעֲבָדָיו, וּבְשִׁירֵי דָּוִד עַבְדֶּךָ נְהַלְלָךָ יהוה אֱלֹהֵינוּ בִּשְׁבָחוֹת וּבִזְמִירוֹת, וּנְגַדְּלָךָ וּנְשַׁבְּחָךָ וּנְפָאֲרָךָ וְנַמְלִיכְךָ וְנַזְכִּיר שִׁמְךָ מַלְכֵּנוּ אֱלֹהֵינוּ, יָחִיד חֵי הָעוֹלָמִים, מֶלֶךְ מְשֻׁבָּח וּמְפֹאָר עֲדֵי עַד שְׁמוֹ הַגָּדוֹל. בָּרוּךְ אַתָּה יהוה, מֶלֶךְ מְהֻלָּל בַּתִּשְׁבָּחוֹת.","cond":[]},{"kind":"text","text":"מִזְמוֹר לְתוֹדָה, הָרִיעוּ לַיהוה כָּל הָאָרֶץ: עִבְדוּ אֶת יהוה בְּשִׂמְחָה, בֹּאוּ לְפָנָיו בִּרְנָנָה: דְּעוּ כִּי יהוה הוּא אֱלֹהִים, הוּא עָשָׂנוּ וְלוֹ אֲנַחְנוּ, עַמּוֹ וְצֹאן מַרְעִיתוֹ: בֹּאוּ שְׁעָרָיו בְּתוֹדָה, חֲצֵרֹתָיו בִּתְהִלָּה, הוֹדוּ לוֹ בָּרְכוּ שְׁמוֹ: כִּי טוֹב יהוה, לְעוֹלָם חַסְדּוֹ, וְעַד דֹּר וָדֹר אֱמוּנָתוֹ:","cond":["toda"]},{"kind":"text","text":"יְהִי כְבוֹד יהוה לְעוֹלָם, יִשְׂמַח יהוה בְּמַעֲשָׂיו: יְהִי שֵׁם יהוה מְבֹרָךְ מֵעַתָּה וְעַד עוֹלָם: מִמִּזְרַח שֶׁמֶשׁ עַד מְבוֹאוֹ מְהֻלָּל שֵׁם יהוה: רָם עַל כָּל גּוֹיִם יהוה, עַל הַשָּׁמַיִם כְּבוֹדוֹ: יהוה שִׁמְךָ לְעוֹלָם, יהוה זִכְרְךָ לְדֹר וָדֹר: יהוה בַּשָּׁמַיִם הֵכִין כִּסְאוֹ וּמַלְכוּתוֹ בַּכֹּל מָשָׁלָה: יִשְׂמְחוּ הַשָּׁמַיִם וְתָגֵל הָאָרֶץ, וְיֹאמְרוּ בַגּוֹיִם יהוה מָלָךְ: יהוה מֶלֶךְ, יהוה מָלָךְ, יהוה יִמְלֹךְ לְעוֹלָם וָעֶד. יהוה מֶלֶךְ עוֹלָם וָעֶד, אָבְדוּ גוֹיִם מֵאַרְצוֹ: יהוה הֵפִיר עֲצַת גּוֹיִם, הֵנִיא מַחְשְׁבוֹת עַמִּים: רַבּוֹת מַחֲשָׁבוֹת בְּלֶב אִישׁ, וַעֲצַת יהוה הִיא תָקוּם: עֲצַת יהוה לְעוֹלָם תַּעֲמֹד, מַחְשְׁבוֹת לִבּוֹ לְדֹר וָדֹר: כִּי הוּא אָמַר וַיֶּהִי, הוּא צִוָּה וַיַּעֲמֹד: כִּי בָחַר יהוה בְּצִיּוֹן, אִוָּהּ לְמוֹשָׁב לוֹ: כִּי יַעֲקֹב בָּחַר לוֹ יָהּ, יִשְׂרָאֵל לִסְגֻלָּתוֹ: כִּי לֹא יִטֹּשׁ יהוה עַמּוֹ וְנַחֲלָתוֹ לֹא יַעֲזֹב: וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית, וְהִרְבָּה לְהָשִׁיב אַפּוֹ וְלֹא יָעִיר כָּל חֲמָתוֹ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":[]},{"kind":"header","text":"אשרי","cond":[]},{"kind":"text","text":"אַשְׁרֵי יוֹשְׁבֵי בֵיתֶךָ עוֹד יְהַלְלוּךָ סֶּלָה:\nאַשְׁרֵי הָעָם שֶׁכָּכָה לּוֹ אַשְׁרֵי הָעָם שֶׁיהוה אֱלֹהָיו:\nתְּהִלָּה לְדָוִד, אֲרוֹמִמְךָ אֱלוֹהַי הַמֶּלֶךְ וַאֲבָרְכָה שִׁמְךָ לְעוֹלָם וָעֶד:\nבְּכָל יוֹם אֲבָרְכֶךָּ וַאֲהַלְלָה שִׁמְךָ לְעוֹלָם וָעֶד:\nגָּדוֹל יהוה וּמְהֻלָּל מְאֹד וְלִגְדֻלָּתוֹ אֵין חֵקֶר:\nדּוֹר לְדוֹר יְשַׁבַּח מַעֲשֶׂיךָ וּגְבוּרֹתֶיךָ יַגִּידוּ:\nהֲדַר כְּבוֹד הוֹדֶךָ וְדִבְרֵי נִפְלְאוֹתֶיךָ אָשִׂיחָה:\nוֶעֱזוּז נוֹרְאֹתֶיךָ יֹאמֵרוּ וּגְדוּלָּתְךָ אֲסַפְּרֶנָּה:\nזֵכֶר רַב טוּבְךָ יַבִּיעוּ וְצִדְקָתְךָ יְרַנֵּנוּ:","cond":[]},{"kind":"text","text":"חַנּוּן וְרַחוּם יהוה אֶרֶךְ אַפַּיִם וּגְדָל חָסֶד:\nטוֹב יהוה לַכֹּל וְרַחֲמָיו עַל כָּל מַעֲשָׂיו:\nיוֹדוּךָ יהוה כָּל מַעֲשֶׂיךָ וַחֲסִידֶיךָ יְבָרְכוּכָה:\nכְּבוֹד מַלְכוּתְךָ יֹאמֵרוּ וּגְבוּרָתְךָ יְדַבֵּרוּ:\nלְהוֹדִיעַ לִבְנֵי הָאָדָם גְּבוּרֹתָיו וּכְבוֹד הֲדַר מַלְכוּתוֹ:\nמַלְכוּתְךָ מַלְכוּת כָּל עֹלָמִים וּמֶמְשַׁלְתְּךָ בְּכָל דּוֹר וָדוֹר:\nסוֹמֵךְ יהוה לְכָל הַנֹּפְלִים וְזוֹקֵף לְכָל הַכְּפוּפִים:\nעֵינֵי כֹל אֵלֶיךָ יְשַׂבֵּרוּ וְאַתָּה נוֹתֵן לָהֶם אֶת אָכְלָם בְּעִתּוֹ:","cond":[]},{"kind":"text","text":"פּוֹתֵחַ אֶת יָדֶךָ וּמַשְׂבִּיעַ לְכָל חַי רָצוֹן:\nצַדִּיק יהוה בְּכָל דְּרָכָיו וְחָסִיד בְּכָל מַעֲשָׂיו:\nקָרוֹב יהוה לְכָל קֹרְאָיו לְכֹל אֲשֶׁר יִקְרָאֻהוּ בֶאֱמֶת:\nרְצוֹן יְרֵאָיו יַעֲשֶׂה וְאֶת שַׁוְעָתָם יִשְׁמַע וְיוֹשִׁיעֵם:\nשׁוֹמֵר יהוה אֶת כָּל אֹהֲבָיו וְאֵת כָּל הָרְשָׁעִים יַשְׁמִיד:\nתְּהִלַּת יהוה יְדַבֶּר פִּי וִיבָרֵךְ כָּל בָּשָׂר שֵׁם קָדְשׁוֹ לְעוֹלָם וָעֶד:\nוַאֲנַחְנוּ נְבָרֵךְ יָהּ מֵעַתָּה וְעַד עוֹלָם הַלְלוּיָהּ:","cond":[]},{"kind":"text","text":"הַלְלוּיָהּ, הַלְלִי נַפְשִׁי אֶת יהוה: אֲהַלְלָה יהוה בְּחַיָּי, אֲזַמְּרָה לֵאלֹהַי בְּעוֹדִי: אַל תִּבְטְחוּ בִנְדִיבִים, בְּבֶן אָדָם שֶׁאֵין לוֹ תְשׁוּעָה: תֵּצֵא רוּחוֹ, יָשֻׁב לְאַדְמָתוֹ, בַּיּוֹם הַהוּא אָבְדוּ עֶשְׁתֹּנֹתָיו: אַשְׁרֵי שֶׁאֵל יַעֲקֹב בְּעֶזְרוֹ, שִׂבְרוֹ עַל יהוה אֱלֹהָיו: עֹשֶׂה שָׁמַיִם וָאָרֶץ, אֶת הַיָּם וְאֶת כָּל אֲשֶׁר בָּם, הַשֹּׁמֵר אֱמֶת לְעוֹלָם: עֹשֶׂה מִשְׁפָּט לָעֲשׁוּקִים, נֹתֵן לֶחֶם לָרְעֵבִים, יהוה מַתִּיר אֲסוּרִים: יהוה פֹּקֵחַ עִוְרִים, יהוה זֹקֵף כְּפוּפִים, יהוה אֹהֵב צַדִּיקִים: יהוה שֹׁמֵר אֶת גֵּרִים, יָתוֹם וְאַלְמָנָה יְעוֹדֵד וְדֶרֶךְ רְשָׁעִים יְעַוֵּת: יִמְלֹךְ יהוה לְעוֹלָם, אֱלֹהַיִךְ צִיּוֹן לְדֹר וָדֹר, הַלְלוּיָהּ:","cond":[]},{"kind":"text","text":"הַלְלוּיָהּ, כִּי טוֹב זַמְּרָה אֱלֹהֵינוּ, כִּי נָעִים נָאוָה תְהִלָּה: בּוֹנֵה יְרוּשָׁלַיִם יהוה, נִדְחֵי יִשְׂרָאֵל יְכַנֵּס: הָרֹפֵא לִשְׁבוּרֵי לֵב וּמְחַבֵּשׁ לְעַצְּבוֹתָם: מוֹנֶה מִסְפָּר לַכּוֹכָבִים, לְכֻלָּם שֵׁמוֹת יִקְרָא: גָּדוֹל אֲדוֹנֵינוּ וְרַב כֹּחַ, לִתְבוּנָתוֹ אֵין מִסְפָּר: מְעוֹדֵד עֲנָוִים יהוה, מַשְׁפִּיל רְשָׁעִים עֲדֵי אָרֶץ: עֱנוּ לַיהוה בְּתוֹדָה, זַמְּרוּ לֵאלֹהֵינוּ בְכִנּוֹר: הַמְכַסֶּה שָׁמַיִם בְּעָבִים, הַמֵּכִין לָאָרֶץ מָטָר, הַמַּצְמִיחַ הָרִים חָצִיר: נוֹתֵן לִבְהֵמָה לַחְמָהּ, לִבְנֵי עֹרֵב אֲשֶׁר יִקְרָאוּ: לֹא בִגְבוּרַת הַסּוּס יֶחְפָּץ, לֹא בְשׁוֹקֵי הָאִישׁ יִרְצֶה: רוֹצֶה יהוה אֶת יְרֵאָיו, אֶת הַמְיַחֲלִים לְחַסְדּוֹ: שַׁבְּחִי יְרוּשָׁלַיִם אֶת יהוה, הַלְלִי אֱלֹהַיִךְ צִיּוֹן: כִּי חִזַּק בְּרִיחֵי שְׁעָרָיִךְ, בֵּרַךְ בָּנַיִךְ בְּקִרְבֵּךְ: הַשָּׂם גְּבוּלֵךְ שָׁלוֹם, חֵלֶב חִטִּים יַשְׂבִּיעֵךְ: הַשֹּׁלֵחַ אִמְרָתוֹ אָרֶץ, עַד מְהֵרָה יָרוּץ דְּבָרוֹ: הַנֹּתֵן שֶׁלֶג כַּצָּמֶר, כְּפוֹר כָּאֵפֶר יְפַזֵּר: מַשְׁלִיךְ קַרְחוֹ כְפִתִּים, לִפְנֵי קָרָתוֹ מִי יַעֲמֹד: יִשְׁלַח דְּבָרוֹ וְיַמְסֵם, יַשֵּׁב רוּחוֹ יִזְּלוּ מָיִם: מַגִּיד דְּבָרָיו לְיַעֲקֹב, חֻקָּיו וּמִשְׁפָּטָיו לְיִשְׂרָאֵל: לֹא עָשָׂה כֵן לְכָל גּוֹי, וּמִשְׁפָּטִים בַּל יְדָעוּם, הַלְלוּיָהּ:","cond":[]},{"kind":"text","text":"הַלְלוּיָהּ, הַלְלוּ אֶת יהוה מִן הַשָּׁמַיִם, הַלְלוּהוּ בַּמְּרוֹמִים: הַלְלוּהוּ כָל מַלְאָכָיו, הַלְלוּהוּ כָּל צְבָאָיו: הַלְלוּהוּ שֶׁמֶשׁ וְיָרֵחַ, הַלְלוּהוּ כָּל כּוֹכְבֵי אוֹר: הַלְלוּהוּ שְׁמֵי הַשָּׁמָיִם וְהַמַּיִם אֲשֶׁר מֵעַל הַשָּׁמָיִם: יְהַלְלוּ אֶת שֵׁם יהוה, כִּי הוּא צִוָּה וְנִבְרָאוּ: וַיַּעֲמִידֵם לָעַד לְעוֹלָם, חָק נָתַן וְלֹא יַעֲבוֹר: הַלְלוּ אֶת יהוה מִן הָאָרֶץ, תַּנִּינִים וְכָל תְּהֹמוֹת: אֵשׁ וּבָרָד, שֶׁלֶג וְקִיטוֹר, רוּחַ סְעָרָה עֹשָׂה דְבָרוֹ: הֶהָרִים וְכָל גְּבָעוֹת, עֵץ פְּרִי וְכָל אֲרָזִים: הַחַיָּה וְכָל בְּהֵמָה, רֶמֶשׂ וְצִפּוֹר כָּנָף: מַלְכֵי אֶרֶץ וְכָל לְאֻמִּים, שָׂרִים וְכָל שֹׁפְטֵי אָרֶץ: בַּחוּרִים וְגַם בְּתוּלוֹת, זְקֵנִים עִם נְעָרִים: יְהַלְלוּ אֶת שֵׁם יהוה כִּי נִשְׂגָּב שְׁמוֹ לְבַדּוֹ, הוֹדוֹ עַל אֶרֶץ וְשָׁמָיִם: וַיָּרֶם קֶרֶן לְעַמּוֹ, תְּהִלָּה לְכָל חֲסִידָיו, לִבְנֵי יִשְׂרָאֵל עַם קְרֹבוֹ, הַלְלוּיָהּ:","cond":[]},{"kind":"text","text":"הַלְלוּיָהּ, שִׁירוּ לַיהוה שִׁיר חָדָשׁ, תְּהִלָּתוֹ בִּקְהַל חֲסִידִים: יִשְׂמַח יִשְׂרָאֵל בְּעֹשָׂיו, בְּנֵי צִיּוֹן יָגִילוּ בְמַלְכָּם: יְהַלְלוּ שְׁמוֹ בְמָחוֹל, בְּתֹף וְכִנּוֹר יְזַמְּרוּ לוֹ: כִּי רוֹצֶה יהוה בְּעַמּוֹ, יְפָאֵר עֲנָוִים בִּישׁוּעָה: יַעְלְזוּ חֲסִידִים בְּכָבוֹד, יְרַנְּנוּ עַל מִשְׁכְּבוֹתָם: רוֹמְמוֹת אֵל בִּגְרוֹנָם וְחֶרֶב פִּיפִיּוֹת בְּיָדָם: לַעֲשׂוֹת נְקָמָה בַּגּוֹיִם, תּוֹכֵחֹת בַּלְאֻמִּים: לֶאְסֹר מַלְכֵיהֶם בְּזִקִּים וְנִכְבְּדֵיהֶם בְּכַבְלֵי בַרְזֶל: לַעֲשׂוֹת בָּהֶם מִשְׁפָּט כָּתוּב, הָדָר הוּא לְכָל חֲסִידָיו, הַלְלוּיָהּ:","cond":[]},{"kind":"text","text":"הַלְלוּיָהּ, הַלְלוּ אֵל בְּקָדְשׁוֹ, הַלְלוּהוּ בִּרְקִיעַ עֻזּוֹ: הַלְלוּהוּ בִגְבוּרֹתָיו, הַלְלוּהוּ כְּרֹב גֻּדְלוֹ: הַלְלוּהוּ בְּתֵקַע שׁוֹפָר, הַלְלוּהוּ בְּנֵבֶל וְכִנּוֹר: הַלְלוּהוּ בְתֹף וּמָחוֹל, הַלְלוּהוּ בְּמִנִּים וְעוּגָב: הַלְלוּהוּ בְצִלְצְלֵי שָׁמַע, הַלְלוּהוּ בְּצִלְצְלֵי תְרוּעָה: כֹּל הַנְּשָׁמָה תְּהַלֵּל יָהּ, הַלְלוּיָהּ: כֹּל הַנְּשָׁמָה תְּהַלֵּל יָהּ, הַלְלוּיָהּ:","cond":[]},{"kind":"text","text":"בָּרוּךְ יהוה לְעוֹלָם, אָמֵן וְאָמֵן: בָּרוּך יהוה מִצִּיּוֹן, שֹׁכֵן יְרוּשָׁלַיִם, הַלְלוּיָהּ: בָּרוּךְ יהוה אֱלֹהִים אֱלֹהֵי יִשְׂרָאֵל, עֹשֶׂה נִפְלָאוֹת לְבַדּוֹ: וּבָרוּךְ שֵׁם כְּבוֹדוֹ לְעוֹלָם, וְיִמָּלֵא כְבוֹדוֹ אֶת כָּל הָאָרֶץ, אָמֵן וְאָמֵן:","cond":[]},{"kind":"instruction","text":"יש לעמוד כשאומרים ויברך דוד עד ישתבח:","cond":[]},{"kind":"text","text":"וַיְבָרֶךְ דָּוִד אֶת יהוה לְעֵינֵי כָּל הַקָּהָל, וַיֹּאמֶר דָּוִד: בָּרוּךְ אַתָּה יהוה אֱלֹהֵי יִשְׂרָאֵל אָבִינוּ, מֵעוֹלָם וְעַד עוֹלָם: לְךָ יהוה הַגְּדֻלָּה, וְהַגְּבוּרָה, וְהַתִּפְאֶרֶת וְהַנֵּצַח וְהַהוֹד, כִּי כָל בַּשָּׁמַיִם וּבָאָרֶץ, לְךָ יהוה הַמַּמְלָכָה וְהַמִּתְנַשֵּׂא לְכָל לְרֹאשׁ: וְהָעֹשֶׁר וְהַכָּבוֹד מִלְּפָנֶיךָ, וְאַתָּה מוֹשֵׁל בַּכֹּל, וּבְיָדְךָ כֹּחַ וּגְבוּרָה וּבְיָדְךָ לְגַדֵּל וּלְחַזֵּק לַכֹּל: וְעַתָּה אֱלֹהֵינוּ מוֹדִים אֲנַחְנוּ לָךְ, וּמְהַלְלִים לְשֵׁם תִפְאַרְתֶּךְ: וִיבָרְכוּ שֵׁם כְּבֹדֶָךָ, וּמֱרוֹמַם עַל כָּל בְּרָכָה וּתְהִלָּה: אַתָּה הוּא יהוה לְבַדֶּךָ, אַתָּה עָשִׂיתָ אֶת הַשָּׁמַיִם, שְׁמֵי הַשָּׁמַיִם וְכָל צְבָאָם, הָאָרֶץ וְכָל אֲשֶׁר עָלֶיהָ, הַיַּמִּים וְכָל אֲשֶׁר בָּהֶם, וְאַתָּה מְחַיֶּה אֶת כֻּלָּם, וּצְבָא הַשָּׁמַיִם לְךָ מִשְׁתַּחֲוִים: אַתָּה הוּא יהוה הָאֱלֹהִים אֲשֶׁר בָּחַרְתָּ בְּאַבְרָם וְהוֹצֵאתוֹ מֵאוּר כַּשְׂדִּים, וְשַׂמְתָּ שְׁמוֹ אַבְרָהָם: וּמָצָאתָ אֶת לְבָבוֹ נֶאֱמָן לְפָנֶיךָ, וְכָרוֹת עִמּוֹ הַבְּרִית לָתֵת אֶת אֶרֶץ הַכְּנַעֲנִי, הַחִתִּי, הָאֱמֹרִי וְהַפְּרִזִּי וְהַיְבוּסִי וְהַגִּרְגָּשִׁי לָתֵת לְזַרְעוֹ, וַתָּקֶם אֶת דְּבָרֶיךָ כִּי צַדִּיק אָתָּה: וַתֵּרֶא אֶת עֳנִי אֲבֹתֵינוּ בְּמִצְרָיִם, וְאֶת זַעֲקָתָם שָׁמַעְתָּ עַל יַם סוּף: וַתִּתֵּן אֹתֹת וּמֹפְתִים בְּפַרְעֹה וּבְכָל עֲבָדָיו וּבְכָל עַם אַרְצוֹ, כִּי יָדַעְתָּ כִּי הֵזִידוּ עֲלֵיהֶם, וַתַּעַשׂ לְךָ שֵׁם כְּהַיּוֹם הַזֶּה: וְהַיָּם בָּקַעְתָּ לִפְנֵיהֶם, וַיַּעַבְרוּ בְתוֹךְ הַיָּם בַּיַּבָּשָׁה, וְאֶת רֹדְפֵיהֶם הִשְׁלַכְתָּ בִמְצוֹלֹת כְּמוֹ אֶבֶן, בְּמַיִם עַזִּים:\n\nוַיּוֹשַׁע יהוה בַּיּוֹם הַהוּא אֶת יִשְׂרָאֵל מִיַּד מִצְרָיִם, וַיַּרְא יִשְׂרָאֵל אֶת מִצְרַיִם מֵת, עַל שְׂפַת הַיָּם: וַיַּרְא יִשְׂרָאֵל אֶת הַיָּד הַגְּדֹלָה אֲשֶׁר עָשָׂה יהוה בְּמִצְרַיִם, וַיִּירְאוּ הָעָם אֶת יהוה, וַיַּאֲמִינוּ בַּיהוה וּבְמֹשֶׁה עַבְדּוֹ:","cond":[]},{"kind":"header","text":"שירת הים","cond":[]},{"kind":"text","text":"אָז יָשִׁיר מֹשֶׁה וּבְנֵי יִשְׂרָאֵל אֶת הַשִּׁירָה הַזֹּאת לַיהוה וַיֹּאמְרוּ לֵּאמֹר, אָשִׁירָה לַיהוה כִּי גָאֹה גָּאָה, סוּס וְרֹכְבוֹ רָמָה בַיָּם: עָזִּי וְזִמְרָת יָהּ וַיְהִי לִי לִישׁוּעָה, זֶה אֵלִי וְאַנְוֵהוּ, אֱלֹהֵי אָבִי וַאֲרֹמְמֶנְהוּ: יהוה אִישׁ מִלְחָמָה, יהוה שְׁמוֹ: מַרְכְּבֹת פַּרְעֹה וְחֵילוֹ יָרָה בַיָּם, וּמִבְחַר שָׁלִשָׁיו טֻבְּעוּ בְיַם סוּף: תְּהֹמֹת יְכַסְיֻמוּ, יָרְדוּ בִמְצוֹלֹת כְּמוֹ אָבֶן: יְמִינְךָ יהוה נֶאְדָּרִי בַּכֹּחַ, יְמִינְךָ יהוה תִּרְעַץ אוֹיֵב: וּבְרֹב גְּאוֹנְךָ תַּהֲרֹס קָמֶיךָ, תְּשַׁלַּח חֲרֹנְךָ יֹאכְלֵמוֹ כַּקַּשׁ: וּבְרוּחַ אַפֶּיךָ נֶעֶרְמוּ מַיִם, נִצְּבוּ כְמוֹ נֵד נֹזְלִים, קָפְאוּ תְהֹמֹת בְּלֶב יָם: אָמַר אוֹיֵב אֶרְדֹּף אַשִּׂיג אֲחַלֵּק שָׁלָל, תִּמְלָאֵמוֹ נַפְשִׁי, אָרִיק חַרְבִּי, תּוֹרִישֵׁמוֹ יָדִי: נָשַׁפְתָּ בְרוּחֲךָ כִּסָּמוֹ יָם, צָלְלוּ כַּעוֹפֶרֶת בְּמַיִם, אַדִּירִים: מִי כָמֹכָה בָּאֵלִם יהוה, מִי כָּמֹכָה נֶאְדָּר בַּקֹּדֶשׁ, נוֹרָא תְהִלֹּת עֹשֵׂה פֶלֶא: נָטִיתָ יְמִינְךָ תִּבְלָעֵמוֹ אָרֶץ: נָחִיתָ בְחַסְדְּךָ עַם זוּ גָּאָלְתָּ, נֵהַלְתָּ בְעָזְּךָ אֶל נְוֵה קָדְשֶׁךָ: שָׁמְעוּ עַמִּים יִרְגָּזוּן, חִיל אָחַז יֹשְׁבֵי פְּלָשֶׁת: אָז נִבְהֲלוּ אַלּוּפֵי אֱדוֹם, אֵילֵי מוֹאָב יֹאחֲזֵמוֹ רָעַד, נָמֹגוּ כָּל יֹשְׁבֵי כְנָעַן: תִּפֹּל עֲלֵיהֶם אֵימָתָה וָפַחַד, בִּגְדֹל זְרוֹעֲךָ יִדְּמוּ כָּאָבֶן, עַד יַעֲבֹר עַמְּךָ, יהוה, עַד יַעֲבֹר עַם זוּ קָנִיתָ: תְּבִאֵמוֹ וְתִטָּעֵמוֹ בְּהַר נַחֲלָתְךָ, מָכוֹן לְשִׁבְתְּךָ פָּעַלְתָּ יהוה, מִקְּדָשׁ, אֲדֹנָי כּוֹנְנוּ יָדֶיךָ: יהוה יִמְלֹךְ לְעֹלָם וָעֶד: יהוה יִמְלֹךְ לְעֹלָם וָעֶד: יהוה מַלְכוּתֵהּ קָאֵם לְעָלַם וּלְעָלְמֵי עָלְמַיָּא. כִּי בָא סוּס פַּרְעֹה בְּרִכְבּוֹ וּבְפָרָשָׁיו בַּיָּם, וַיָּשֶׁב יהוה עֲלֵהֶם אֶת מֵי הַיָּם, וּבְנֵי יִשְׂרָאֵל הָלְכוּ בַיַּבָּשָׁה בְּתוֹךְ הַיָּם: כִּי לַיהוה הַמְּלוּכָה וּמֹשֵׁל בַּגּוֹיִם: וְעָלוּ מוֹשִׁעִים בְּהַר צִיּוֹן לִשְׁפֹּט אֶת הַר עֵשָׂו, וְהָיְתָה לַיהוה הַמְּלוּכָה: וְהָיָה יהוה לְמֶלֶךְ עַל כָּל הָאָרֶץ, בַּיּוֹם הַהוּא יִהְיֶה יהוה אֶחָד וּשְׁמוֹ אֶחָד:","cond":[]},{"kind":"text","text":"וּבְתוֹרָתְךָ כָּתוּב לֵאמֹר: שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:\n\nיִשְׁתַּבַּח שִׁמְךָ לָעַד מַלְכֵּנוּ, הָאֵל הַמֶּלֶךְ הַגָּדוֹל וְהַקָּדוֹשׁ בַּשָּׁמַיִם וּבָאָרֶץ, כִּי לְךָ נָאֶה, יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שִׁיר וּשְׁבָחָה, הַלֵּל וְזִמְרָה, עֹז וּמֶמְשָׁלָה, נֶצַח, גְּדֻלָּה וּגְבוּרָה, תְּהִלָּה וְתִפְאֶרֶת, קְדֻשָּׁה וּמַלְכוּת. בְּרָכוֹת וְהוֹדָאוֹת לְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ, וּמֵעוֹלָם וְעַד עוֹלָם אַתָּה אֵל. בָּרוּךְ אַתָּה יהוה, אֵל מֶלֶךְ גָּדוֹל וּמְהֻלָּל בַּתִּשְׁבָּחוֹת, אֵל הַהוֹדָאוֹת, אֲדוֹן הַנִּפְלָאוֹת, בּוֹרֵא כָל הַנְּשָׁמוֹת, רִבּון כָּל הַמַּעֲשִׂים, הַבּוֹחֵר בְּשִׁירֵי זִמְרָה, מֶלֶךְ יָחִיד, אֵל חֵי הָעוֹלָמִים.","cond":[]},{"kind":"header","text":"שיר המעלות","cond":["ayt"]},{"kind":"special","text":"שִׁיר הַמַּעֲלוֹת, מִמַּעֲמַקִּים קְרָאתִיךָ יהוה: אֲדֹנָי, שִׁמְעָה בְקוֹלִי, תִּהְיֶינָה אָזְנֶיךָ קַשֻּׁבוֹת לְקוֹל תַּחֲנוּנָי: אִם עֲוׂנוֹת תִּשְׁמָר יָהּ, אֲדֹנָי מִי יַעֲמֹד: כִּי עִמְּךָ הַסְּלִיחָה לְמַעַן תִּוָּרֵא: קִוִּיתִי יהוה, קִוְּתָה נַפְשִׁי, וְלִדְבָרוֹ הוֹחָלְתִּי: נַפְשִׁי לַאדֹנָי, מִשֹּׁמְרִים לַבֹּקֶר, שֹׁמְרִים לַבֹּקֶר: יַחֵל יִשְׂרָאֵל אֶל יהוה, כִּי עִם יהוה הַחֶסֶד וְהַרְבֵּה עִמּוֹ פְדוּת: וְהוּא יִפְדֶּה אֶת יִשְׂרָאֵל מִכֹּל עֲוֹנֹתָיו:","cond":["ayt"]},{"kind":"instruction","text":"חצי קדיש","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":[]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"header","text":"קריאת שמע וברכותיה","cond":[]},{"kind":"instruction","text":"ברכות קריאת שמע","cond":[]},{"kind":"instruction","text":"חזן:","cond":[]},{"kind":"text","text":"בָּרְכוּ אֶת יהוה הַמְבֹרָךְ.","cond":[]},{"kind":"instruction","text":"קהל וחזן:","cond":[]},{"kind":"text","text":"בָּרוּךְ יהוה הַמְבֹרָךְ לְעוֹלָם וָעֶד.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, יוֹצֵר אוֹר וּבוֹרֵא חֹשֶׁךְ, עֹשֶׂה שָׁלוֹם וּבוֹרֵא אֶת הַכֹּל.\n\nהַמֵּאִיר לָאָרֶץ וְלַדָּרִים עָלֶיהָ בְּרַחֲמִים, וּבְטוּבוֹ מְחַדֵּשׁ בְּכָל יוֹם תָּמִיד מַעֲשֵׂה בְרֵאשִׁית. מָה רַבּוּ מַעֲשֶׂיךָ יהוה, כֻּלָם בְּחָכְמָה עָשִׂיתָ, מָלְאָה הָאָרֶץ קִנְיָנֶךָ: הַמֶּלֶךְ הַמְרוֹמָם לְבַדּוֹ מֵאָז, הַמְשֻׁבָּח וְהַמְפֹאָר וְהַמִּתְנַשֵּׂא מִימוֹת עוֹלָם. אֱלֹהֵי עוֹלָם, בְּרַחֲמֶיךָ הָרַבִּים רַחֵם עָלֵינוּ, אֲדוֹן עֻזֵּנוּ, צוּר מִשְׂגַּבֵּנוּ, מָגֵן יִשְׁעֵנוּ, מִשְׂגָּב בַּעֲדֵנוּ. אֵל בָּרוּךְ גְּדוֹל דֵּעָה, הֵכִין וּפָעַל זָהֳרֵי חַמָּה, טוֹב יָצַר כָּבוֹד לִשְׁמוֹ, מְאוֹרוֹת נָתַן סְבִיבוֹת עֻזּוֹ, פִּנּוֹת צְבָאָיו קְדוֹשִׁים, רוֹמְמֵי שַׁדַּי, תָּמִיד מְסַפְּרִים כְּבוֹד אֵל וּקְדֻשָּׁתוֹ. תִּתְבָּרַךְ יהוה אֱלֹהֵינוּ בַּשָּׁמַיִם מִמַּעַל וְעַל הָאָרֶץ מִתָּחַת עַל כָּל שֶׁבַח מַעֲשֵׂה יָדֶיךָ וְעַל מְאוֹרֵי אוֹר שֶׁיָּצַרְתָּ, הֵמָּה יְפַאֲרוּךָ סֶּלָה. תִּתְבָּרַךְ לָנֶצַח צוּרֵנוּ מַלְכֵּנוּ וְגוֹאֲלֵנוּ בּוֹרֵא קְדוֹשִׁים, יִשְׁתַּבַּח שִׁמְךָ לָעַד מַלְכֵּנוּ יוֹצֵר מְשָׁרְתִים, וַאֲשֶׁר מְשָׁרְתָיו כֻּלָּם עוֹמְדִים בְּרוּם עוֹלָם וּמַשְׁמִיעִים בְּיִרְאָה יַחַד בְּקוֹל דִּבְרֵי אֱלֹהִים חַיִּים וּמֶלֶךְ עוֹלָם. כֻּלָּם אֲהוּבִים, כֻּלָּם בְּרוּרִים, כֻּלָּם גִּבּוֹרִים, כֻּלָּם קְדוֹשִׁים, וְכֻלָּם עוֹשִׂים בְּאֵימָה וּבְיִרְאָה רְצוֹן קוֹנָם, וְכֻלָּם פּוֹתְחִים אֶת פִּיהֶם בִּקְדֻשָּׁה וּבְטָהֳרָה, בְּשִׁירָה וּבְזִמְרָה, וּמְבָרְכִין וּמְשַׁבְּחִין וּמְפַאֲרִין וּמַעֲרִיצִין וּמַקְדִּישִׁין וּמַמְלִיכִין\n\nאֶת שֵׁם הָאֵל הַמֶּלֶךְ הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא, קָדוֹשׁ הוּא. וְכֻלָּם מְקַבְּלִים עֲלֵיהֶם עֹל מַלְכוּת שָׁמַיִם זֶה מִזֶּה, וְנוֹתְנִים בְּאַהֲבָה רְשׁוּת זֶה לָזֶה לְהַקְדִּישׁ לְיוֹצְרָם בְּנַחַת רוּחַ, בְּשָׂפָה בְרוּרָה וּבִנְעִימָה, קְדֻשָּׁה כֻּלָּם כְּאֶחָד עוֹנִים בְּאֵימָה וְאוֹמְרִים בְּיִרְאָה:\n\nקָדוֹשׁ, קָדוֹשׁ, קָדוֹשׁ יהוה צְבָאוֹת, מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ:\n\nוְהָאוֹפַנִּים וְחַיּוֹת הַקֹּדֶשׁ בְּרַעַשׁ גָּדוֹל מִתְנַשְּׂאִים לְעֻמַּת שְׂרָפִים, לְעֻמָּתָם מְשַׁבְּחִים וְאוֹמְרִים:\n\nבָּרוּךְ כְּבוֹד יהוה מִמְּקוֹמוֹ:\n\nלְאֵל בָּרוּךְ נְעִימוֹת יִתֵּנוּ, לְמֶלֶךְ אֵל חַי וְקַיָּם זְמִירוֹת יֹאמֵרוּ וְתִשְׁבָּחוֹת יַשְׁמִיעוּ, כִּי הוּא לְבַדּוֹ מָרוֹם וְקָדוֹשׁ, פּוֹעֵל גְּבוּרוֹת, עוֹשֶׂה חֲדָשׁוֹת, בַּעַל מִלְחָמוֹת, זוֹרֵעַ צְדָקוֹת, מַצְמִיחַ יְשׁוּעוֹת, בּוֹרֵא רְפוּאוֹת, נוֹרָא תְהִלּוֹת, אֲדוֹן הַנִּפְלָאוֹת, הַמְחַדֵּשׁ בְּטוּבוֹ בְּכָל יוֹם תָּמִיד מַעֲשֵׂה בְרֵאשִׁית, כָּאָמוּר: לְעֹשֵׂה אוֹרִים גְּדֹלִים, כִּי לְעוֹלָם חַסְדּוֹ: וְהִתְקִין מְאוֹרוֹת, מְשַׂמֵּחַ עוֹלָמוֹ אֲשֶׁר בָּרָא. אוֹר חָדָשׁ עַל צִיּוֹן תָּאִיר וְנִזְכֶּה כֻלָּנוּ בִּמְהֵרָה לְאוֹרוֹ. בָּרוּךְ אַתָּה יהוה, יוֹצֵר הַמְּאוֹרוֹת.\n\n\nאַהֲבַת עוֹלָם אֲהַבְתָּנוּ, יהוה אֱלֹהֵינוּ, חֶמְלָה גְּדוֹלָה וִיתֵרָה חָמַלְתָּ עָלֵינוּ. אָבִינוּ מַלְכֵּנוּ, בַּעֲבוּר שִׁמְךָ הַגָּדוֹל וּבַעֲבוּר אֲבוֹתֵינוּ שֶׁבָּטְחוּ בְךָ, וַתְּלַמְּדֵם חֻקֵּי חַיִּים לַעֲשׂוֹת רְצוֹנְךָ בְּלֵבָב שָׁלֵם, כֵּן תְּחָנֵּנוּ וּתְלַמְּדֵנוּ. אָבִינוּ אָב הָרַחֲמָן, הַמְרַחֵם, רַחֵם עָלֵינוּ, וְתֵן בְּלִבֵּנוּ בִּינָה לְהָבִין וּלְהַשְׂכִּיל, לִשְׁמֹעַ, לִלְמֹד וּלְלַמֵּד, לִשְׁמֹר וְלַעֲשׂוֹת וּלְקַיֵּם אֶת כָּל דִּבְרֵי תַלְמוּד תּוֹרָתֶךָ בְּאַהֲבָה. וְהָאֵר עֵינֵינוּ בְּתוֹרָתֶךָ, וְדַבֵּק לִבֵּנוּ בְּמִצְוׂתֶיךָ, וְיַחֵד לְבָבֵנוּ לְאַהֲבָה וּלְיִרְאָה אֶת שְׁמֶךָ, לְמַעַן לֹא נֵבוֹשׁ וְלֹא נִכָּלֵם וְלֹא נִכָּשֵׁל לְעוֹלָם וָעֶד. כִּי בְשֵׁם קָדְשְׁךָ הַגָּדוֹל, הַגִּבּוֹר וְהַנּוֹרָא בָּטָחְנוּ, נָגִילָה וְנִשְׂמְחָה בִּישׁוּעָתֶךָ. וְרַחֲמֶיךָ יהוה אֱלֹהֵינוּ וַחֲסָדֶיךָ הָרַבִּים אַל יַעַזְבוּנוּ נֶצַח סֶלָה וָעֶד. מַהֵר וְהָבֵא עָלֵינוּ בְּרָכָה וְשָׁלוֹם מֵאַרְבַּע כַּנְפוֹת כָּל הָאָרֶץ, וּשְׁבוֹר עֻלֵּנוּ מֵעַל צַוָּארֵנוּ, וְתוֹלִיכֵנוּ מְהֵרָה קוֹמְמִיּוּת לְאַרְצֵנוּ. כִּי אֵל פּוֹעֵל יְשׁוּעוֹת אָתָּה, וּבָנוּ בָחַרְתָּ מִכָּל עַם וְלָשׁוֹן, וְקֵרַבְתָּנוּ מַלְכֵּנוּ לְשִׁמְךָ הַגָּדוֹל סֶלָה בֶּאֱמֶת בְּאַהֲבָה לְהוֹדוֹת לְךָ וּלְיַחֶדְךָ בְּאַהֲבָה, וּלְאַהֲבָה אֶת שְׁמֶךָ. בָּרוּךְ אַתָּה יהוה, הַבּוֹחֵר בְּעַמּוֹ יִשְׂרָאֵל בְּאַהֲבָה.","cond":[]},{"kind":"header","text":"קריאת שמע","cond":[]},{"kind":"instruction","text":"קריאת שמע\n\nיחיד אומר:","cond":[]},{"kind":"text","text":"אֵל מֶלֶךְ נֶאֱמָן.","cond":[]},{"kind":"text","text":"שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:","cond":[]},{"kind":"instruction","text":"בלחש:","cond":[]},{"kind":"text","text":"בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד.\n\nוְאָהַבְתָּ אֵת יהוה אֱלֹהֶיךָ, בְּכָל לְבָבְךָ וּבְכָל נַפְשְׁךָ וּבְכָל מְאֹדֶךָ: וְהָיוּ הַדְּבָרִים הָאֵלֶּה אֲשֶׁר אָנֹכִי מְצַוְּךָ הַיּוֹם, עַל לְבָבֶךָ: וְשִׁנַּנְתָּם לְבָנֶיךָ וְדִבַּרְתָּ בָּם, בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ: וּקְשַׁרְתָּם לְאוֹת עַל יָדֶךָ, וְהָיוּ לְטֹטָפֹת בֵּין עֵינֶיךָ: וּכְתַבְתָּם עַל מְזֻזוֹת בֵּיתֶךָ וּבִשְׁעָרֶיךָ:","cond":[]},{"kind":"text","text":"וְהָיָה אִם שָׁמֹעַ תִּשְׁמְעוּ אֶל מִצְוׂתַי, אֲשֶׁר אָנֹכִי מְצַוֶּה אֶתְכֶם הַיּוֹם, לְאַהֲבָה אֶת יהוה אֱלֹהֵיכֶם וּלְעָבְדוֹ, בְּכָל לְבַבְכֶם וּבְכָל נַפְשְׁכֶם: וְנָתַתִּי מְטַר אַרְצְכֶם בְּעִתּוֹ, יוֹרֶה וּמַלְקוֹשׁ, וְאָסַפְתָּ דְגָנֶךָ וְתִירֹשְׁךָ וְיִצְהָרֶךָ: וְנָתַתִּי עֵשֶׂב בְּשָׂדְךָ לִבְהֶמְתֶּךָ, וְאָכַלְתָּ וְשָׂבָעְתָּ: הִשָּׁמְרוּ לָכֶם פֶּן יִפְתֶּה לְבַבְכֶם, וְסַרְתֶּם וַעֲבַדְתֶּם אֱלֹהִים אֲחֵרִים וְהִשְׁתַּחֲוִיתֶם לָהֶם: וְחָרָה אַף יהוה בָּכֶם, וְעָצַר אֶת הַשָּׁמַיִם וְלֹא יִהְיֶה מָטָר, וְהָאֲדָמָה לֹא תִתֵּן אֶת יְבוּלָהּ, וַאֲבַדְתֶּם מְהֵרָה מֵעַל הָאָרֶץ הַטֹּבָה אֲשֶׁר יהוה נֹתֵן לָכֶם: וְשַׂמְתֶּם אֶת דְּבָרַי אֵלֶּה עַל לְבַבְכֶם וְעַל נַפְשְׁכֶם, וּקְשַׁרְתֶּם אֹתָם לְאוֹת עַל יֶדְכֶם וְהָיוּ לְטוֹטָפֹת בֵּין עֵינֵיכֶם: וְלִמַּדְתֶּם אֹתָם אֶת בְּנֵיכֶם לְדַבֵּר בָּם, בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ: וּכְתַבְתָּם עַל מְזוּזוֹת בֵּיתֶךָ וּבִשְׁעָרֶיךָ: לְמַעַן יִרְבּוּ יְמֵיכֶם וִימֵי בְנֵיכֶם עַל הָאֲדָמָה אֲשֶׁר נִשְׁבַּע יהוה לַאֲבֹתֵיכֶם לָתֵת לָהֶם, כִּימֵי הַשָּׁמַיִם עַל הָאָרֶץ:","cond":[]},{"kind":"text","text":"וַיֹּאמֶר יהוה אֶל מֹשֶׁה לֵּאמֹר: דַּבֵּר אֶל בְּנֵי יִשְׂרָאֵל וְאָמַרְתָּ אֲלֵהֶם, וְעָשׂוּ לָהֶם צִיצִת עַל כַּנְפֵי בִגְדֵיהֶם לְדֹרֹתָם, וְנָתְנוּ עַל צִיצִת הַכָּנָף פְּתִיל תְּכֵלֶת: וְהָיָה לָכֶם לְצִיצִת, וּרְאִיתֶם אֹתוֹ, וּזְכַרְתֶּם אֶת כָּל מִצְוׂת יהוה וַעֲשִׂיתֶם אֹתָם, וְלֹא תָתֻרוּ אַחֲרֵי לְבַבְכֶם וְאַחֲרֵי עֵינֵיכֶם אֲשֶׁר אַתֶּם זֹנִים אַחֲרֵיהֶם: לְמַעַן תִּזְכְּרוּ וַעֲשִׂיתֶם אֶת כָּל מִצְוׂתָי, וִהְיִיתֶם קְדֹשִׁים לֵאלֹהֵיכֶם: אֲנִי יהוה אֱלֹהֵיכֶם אֲשֶׁר הוֹצֵאתִי אֶתְכֶם מֵאֶרֶץ מִצְרַיִם, לִהְיוֹת לָכֶם לֵאלֹהִים, אֲנִי יהוה אֱלֹהֵיכֶם:","cond":[]},{"kind":"text","text":"אֱמֶת","cond":[]},{"kind":"instruction","text":"הש\"ץ חוזר ואומר:","cond":[]},{"kind":"text","text":"יהוה אֱלֹהֵיכֶם: אֱמֶת","cond":[]},{"kind":"instruction","text":"הברכה שאחרי קריאת שמע","cond":[]},{"kind":"text","text":"וְיַצִּיב, וְנָכוֹן, וְקַיָּם, וְיָשָׁר, וְנֶאֱמָן, וְאָהוּב, וְחָבִיב, וְנֶחְמָד, וְנָעִים, וְנוֹרָא, וְאַדִּיר, וּמְתֻקָּן, וּמְקֻבָּל, וְטוֹב, וְיָפֶה, הַדָּבָר הַזֶּה עָלֵינוּ לְעוֹלָם וָעֶד.","cond":[]},{"kind":"instruction","text":"לאחר אמירת \"נאמנים ונחמדים לעד\" ינשק הציצית ויניחם מידיו.","cond":[]},{"kind":"text","text":"אֱמֶת, אֱלֹהֵי עוֹלָם מַלְכֵּנוּ, צוּר יַעֲקֹב מָגֵן יִשְׁעֵנוּ, לְדוֹר וָדוֹר הוּא קַיָּם, וּשְׁמוֹ קַיָּם, וְכִסְאוֹ נָכוֹן, וּמַלְכוּתו וֶאֱמוּנָתו לָעַד קַיָּמֶת, וּדְבָרָיו חַיִּים וְקַיָּמִים, וְנֶאֱמָנִים וְנֶחֱמָדִים לָעַד וּלְעוֹלְמֵי עוֹלָמִים, עַל אֲבוֹתֵינוּ וְעָלֵינוּ, עַל בָּנֵינוּ וְעַל דּוֹרוֹתֵינוּ, וְעַל כָּל דּוֹרוֹת זֶרַע יִשְׂרָאֵל עֲבָדֶיךָ, עַל הָרִאשׁוֹנִים וְעַל הָאַחֲרוֹנִים דָּבָר טוֹב וְקַיָּם לְעוֹלָם וָעֶד, אֱמֶת וֶאֱמוּנָה חֹק וְלֹא יַעֲבוֹר. אֱמֶת שָׁאַתָּה הוּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מַלְכֵּנוּ מֶלֶךְ אֲבוֹתֵינוּ, גּוֹאֲלֵנוּ גּוֹאֵל אֲבוֹתֵינוּ, יוֹצְרֵנוּ צוּר יְשׁוּעָתֵנוּ, פּוֹדֵנוּ וּמַצִּילֵנוּ מֵעוֹלָם הוּא שְׁמֶךָ, וְאֵין לָנוּ עוֹד אֱלֹהִים זוּלָתְךָ, סֶלָה.\n\nעֶזְרַת אֲבוֹתֵינוּ אַתָּה הוּא מֵעוֹלָם, מָגֵן וּמושִׁיעַ לָהֶם וְלִבְנֵיהֶם אַחֲרֵיהֶם בְּכָל דּוֹר וָדוֹר, בְּרוּם עוֹלָם מוֹשָׁבֶךָ, וּמִשְׁפָּטֶיךָ, וְצִדְקָתְךָ עַד אַפְסֵי אָרֶץ. אֱמֶת, אַשְׁרֵי אִישׁ שֶׁיִּשְׁמַע לְמִצְוׂתֶיךָ, וְתוֹרָתְךָ וּדְבָרְךָ יָשִׂים עַל לִבּוֹ. אֱמֶת, אַתָּה הוּא אֲדוֹן לְעַמֶּךָ וּמֶלֶךְ גִּבּוֹר לָרִיב רִיבָם לְאָבוֹת וּבָנִים. אֱמֶת, אַתָּה הוּא רִאשׁוֹן, וְאַתָּה הוּא אַחֲרוֹן, וּמִבַּלְעָדֶיךָ אֵין לָנוּ מֶלֶךְ גּוֹאֵל וּמוֹשִׁיעַ. אֱמֶת, מִמִּצְרַיִם גְּאַלְתָּנוּ יהוה אֱלֹהֵינוּ, וּמִבֵּית עֲבָדִים פְּדִיתָנוּ, כָּל בְּכוֹרֵיהֶם הָרַגְתָּ, וּבְכוֹרְךָ יִשְׂרָאֵל גָּאַלְתָּ, וְיַם סוּף לָהֶם בָּקַעְתָּ, וְזֵדִים טִבַּעְתָּ, וִידִידִים הֶעֱבַרְתָּ, וַיְכַסּוּ מַיִם צָרֵיהֶם, אֶחָד מֵהֶם לֹא נוֹתַר. עַל זֹאת שִׁבְּחוּ אֲהוּבִים, וְרוֹמְמוּ לָאֵל, וְנָתְנוּ יְדִידִים זְמִירוֹת שִׁירוֹת וְתִשְׁבָּחוֹת בְּרָכוֹת וְהוֹדָאוֹת לְמֶלֶךְ אֵל חַי וְקַיָּם, רָם וְנִשָּׂא, גָּדוֹל וְנוֹרָא, מַשְׁפִּיל גֵּאִים עֲדֵי אָרֶץ וּמַגְבִּיהַּ שְׁפָלִים עֲדֵי מָרוֹם, מוֹצִיא אֲסִירִים וּפוֹדֶה עֲנָוִים, וְעוֹזֵר דַּלִּים, וְעוֹנֶה לְעַמּוֹ בְּעֵת שַׁוְּעָם אֵלָיו. תְּהִלּוֹת לְאֵל עֶלְיוֹן גּוֹאֲלָם, בָּרוּךְ הוּא וּמְבֹרָךְ, מֹשֶׁה וּבְנֵי יִשְׂרָאֵל לְךָ עָנוּ שִׁירָה, בְּשִׂמְחָה רַבָּה, וְאָמְרוּ כֻלָּם:\n\nמִי כָמֹכָה בָּאֵלִם יהוה, מִי כָּמֹכָה נֶאְדָּר בַּקֹּדֶשׁ, נוֹרָא תְהִלֹּת עֹשֵׂה פֶלֶא:\n\nשִׁירָה חֲדָשָׁה שִׁבְּחוּ גְאוּלִים לְשִׁמְךָ הַגָּדוֹל עַל שְׂפַת הַיָּם, יַחַד כֻּלָם הוֹדוּ וְהִמְלִיכוּ וְאָמְרוּ:\n\nיהוה יִמְלֹךְ לְעֹלָם וָעֶד:\n\nצוּר יִשְׂרָאֵל, קוּמָה בְּעֶזְרַת יִשְׂרָאֵל, וּפְדֵה כִנְאֻמֶּךָ יְהוּדָה וְיִשְׂרָאֵל. וְנֶאֱמַר: גֹאֲלֵנוּ יהוה צְבָאוֹת שְׁמוֹ, קְדוֹשׁ יִשְׂרָאֵל: בָּרוּךְ אַתָּה יהוה, גָּאַל יִשְׂרָאֵל.","cond":[]},{"kind":"header","text":"עמידה","cond":[]},{"kind":"instruction","text":"תפילת העמידה","cond":[]},{"kind":"text","text":"אֲדֹנָי, שְׂפָתַי תִּפְתָּח, וּפִי יַגִּיד תְּהִלָּתֶךָ:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק, וֵאלֹהֵי יַעֲקֹב, הָאֵל הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, וְקוֹנֵה הַכֹּל, וְזוֹכֵר חַסְדֵי אָבוֹת, וּמֵבִיא גוֹאֵל לִבְנֵי בְנֵיהֶם לְמַעַן שְׁמוֹ בְּאַהֲבָה.","cond":[]},{"kind":"special","text":"זָכְרֵנוּ לְחַיִּים, מֶלֶךְ חָפֵץ בַּחַיִּים, וְכָתְבֵנוּ בְּסֵפֶר הַחַיִּים, לְמַעַנְךָ אֱלֹהִים חַיִּים.","cond":["ayt"]},{"kind":"text","text":"מֶלֶךְ עוֹזֵר וּמוֹשִׁיעַ וּמָגֵן. בָּרוּךְ אַתָּה יהוה, מָגֵן אַבְרָהָם.","cond":[]},{"kind":"text","text":"אַתָּה גִּבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֵּה מֵתִים אַתָּה רַב לְהוֹשִׁיעַ,","cond":[]},{"kind":"summer","text":"מוֹרִיד הַטָּל,","cond":["summerTal"]},{"kind":"winter","text":"מַשִּׁיב הָרוּחַ וּמוֹרִיד הַגֶּשֶׁם,","cond":["winterTal"]},{"kind":"text","text":"מְכַלְכֵּל חַיִּים בְּחֶסֶד, מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים, סוֹמֵךְ נוֹפְלִים, וְרוֹפֵא חוֹלִים וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמוּנָתוֹ לִישֵׁנֵי עָפָר. מִי כָמוֹךָ בַּעַל גְּבוּרוֹת וּמִי דּוֹמֶה לָךְ, מֶלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִיחַ יְשׁוּעָה.","cond":[]},{"kind":"special","text":"מִי כָמוֹךָ אַב הָרַחֲמָן, זוֹכֵר יְצוּרָיו לְחַיִּים בְּרַחֲמִים.","cond":["ayt"]},{"kind":"text","text":"וְנֶאֱמָן אַתָּה לְהַחֲיוֹת מֵתִים. בָּרוּךְ אַתָּה יהוה, מְחַיֵּה הַמֵּתִים.","cond":[]},{"kind":"text","text":"אַתָּה קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ וּקְדוֹשִׁים בְּכָל יוֹם יְהַלְלוּךָ סֶּלָה, כִּי אֵל מֶלֶךְ גָּדוֹל וְקָדוֹשׁ אָתָּה.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הָאֵל הַקָּדוֹשׁ.","cond":["noayt"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יהוה, הַמֶּלֶךְ הַקָּדוֹשׁ.","cond":["ayt"]},{"kind":"text","text":"אַתָּה חוֹנֵן לְאָדָם דַּעַת וּמְלַמֵּד לֶאֱנוֹשׁ בִּינָה.","cond":[]},{"kind":"text","text":"חָנֵּנוּ מִאִתְּךָ חָכְמָה בִּינָה וָדָעַת","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, חוֹנֵן הַדָּעַת.","cond":[]},{"kind":"text","text":"הֲשִׁיבֵנוּ אָבִינוּ לְתוֹרָתֶךָ, וְקָרְבֵנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶך, וְהַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ. בָּרוּךְ אַתָּה יהוה, הָרוֹצֶה בִּתְשׁוּבָה.","cond":[]},{"kind":"text","text":"סְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ, כִּי אֵל טוֹב וְסַלָּח אָתָּה. בָּרוּךְ אַתָּה יהוה, חַנּוּן הַמַּרְבֶּה לִסְלֹחַ.","cond":[]},{"kind":"text","text":"רְאֵה נָא בְעָנְיֵנוּ, וְרִיבָה רִיבֵנוּ, וּגְאָלֵנוּ גְאֻלָּה שְׁלֵמָה מְהֵרָה לְמַעַן שְׁמֶךָ, כִּי אֵל גּוֹאֵל חָזָק אָתָּה. בָּרוּךְ אַתָּה יהוה, גּוֹאֵל יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"רְפָאֵנוּ יהוה וְנֵרָפֵא, הוֹשִׁיעֵנוּ וְנִוָּשֵׁעָה כִּי תְהִלָּתֵנוּ אָתָּה, וְהַעֲלֵה (אֲרוּכָה וּמַרְפֵּא לְכָל תַּחֲלוּאֵינוּ וּלְכָל מַכְאוֹבֵינוּ) רְפוּאָה שְׁלֵמָה לְכָל מַכּוֹתֵינוּ.","cond":[]},{"kind":"special","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁתִּשְׁלַח מְהֵרָה רְפוּאָה שְׁלֵמָה מִן הַשָּׁמַיִם, רְפוּאַת הַנֶּפֶשׁ וּרְפוּאַת הַגּוּף לַחוֹלֶה (לנקבה: לַחוֹלָה, לרבים: לַחוֹלִים, לרבות: לַחוֹלוֹת):\n:=:=\nבְּתוֹךְ שְׁאָר חוֹלֵי יִשְׂרָאֵל.","cond":["doctor"]},{"kind":"text","text":"כִּי אֵל מֶלֶךְ רוֹפֵא נֶאֱמָן וְרַחֲמָן אָתָּה. בָּרוּךְ אַתָּה יהוה, רוֹפֵא חוֹלֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"בָּרֵך עָלֵינוּ יהוה אֱלֹהֵינוּ אֶת הַשָּׁנָה הַזֹּאת וְאֶת כָּל מִינֵי תְבוּאָתָהּ לְטוֹבָה, וְתֵן","cond":[]},{"kind":"summer","text":"בְּרָכָה","cond":["summerBracha"]},{"kind":"winter","text":"טַל וּמָטָר לִבְרָכָה","cond":["winterBracha"]},{"kind":"text","text":"עַל פְּנֵי הָאֲדָמָה וְשַׂבְּעֵנוּ מִטּוּבָהּ, וּבָרֵךְ שְׁנָתֵנוּ כַּשָּׁנִים הַטּוֹבוֹת לִבְרָכָה. כִּי אֵל טוֹב וּמֵטִיב אַתָּה וּמְבָרֵךְ הַשָּׁנִים. בָּרוּךְ אַתָּה יהוה, מְבָרֵךְ הַשָּׁנִים.","cond":[]},{"kind":"text","text":"תְּקַע בְּשׁוֹפָר גָּדוֹל לְחֵרוּתֵנוּ וְשָׂא נֵס לְקַבֵּץ גָּלֻיּוֹתֵינוּ, וְקַבְּצֵנוּ יַחַד מְהֵרָה מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ לְאַרְצֵנוּ. בָּרוּךְ אַתָּה יהוה, מְקַבֵּץ נִדְחֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"הָשִׁיבָה שׁוֹפְטֵינוּ כְּבָרִאשׁוֹנָה וְיוֹעֲצֵינוּ כְּבַתְּחִלָּה, וְהָסֵר מִמֶּנּוּ יָגוֹן וַאֲנָחָה, וּמְלֹךְ עָלֵינוּ מְהֵרָה אַתָּה יהוה לְבַדְּךָ בְּחֶסֶד וּבְרַחֲמִים, בְּצֶדֶק וּבְמִשְׁפָט.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, מֶלֶךְ אוֹהֵב צְדָקָה וּמִשְׁפָּט.","cond":["noayt"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יהוה, הַמֶּלֶךְ הַמִּשְׁפָּט.","cond":["ayt"]},{"kind":"text","text":"וְלַמַּלְשִׁינִים אַל תְּהִי תִקְוָה, וְכָל הַמִּינִים כְּרֶגַע יֹאבֵדוּ. וְכָל אוֹיְבֵי עַמְּךָ מְהֵרָה יִכָּרֵתוּ, וְהַזֵּדִים מְהֵרָה תְעַקֵּר וּתְשַׁבֵּר וּתְמַגֵּר וּתְכַלֵּם וְתַשְׁפִּילֵם וְתַכְנִיעֵם בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יהוה, שׁוֹבֵר אוֹיְבִים וּמַכְנִיעַ זֵדִים.","cond":[]},{"kind":"text","text":"עַל הַצַּדִּיקִים וְעַל הַחֲסִידִים, וְעַל זִקְנֵי שְׁאֵרִית עַמְּךָ בֵּית יִשְׂרָאֵל, וְעַל פְּלֵיטַת בֵּית סוֹפרֵיהֶם, וְעַל גֵּרֵי הַצֶדֶק וְעָלֵינוּ, יֶהֱמוּ נָא רַחֲמֶיךָ יהוה אֱלֹהֵינוּ, וְתֵן שָׂכָר טוֹב לְכָל הַבּוֹטְחִים בְּשִׁמְךָ בֶּאֱמֶת, וְשִׂים חֶלְקֵנוּ עִמָּהֶם וּלְעוֹלָם לֹא נֵבוֹשׁ כִּי בְךָ בָטָחְנוּ וְעַל חַסְדְּךָ הַגָּדוֹל בֶּאֱמֶת (וּבְתָמִים) נִשְׁעַנּוּ. בָּרוּךְ אַתָּה יהוה, מִשְׁעָן וּמִבְטָח לַצַּדִּיקִים.","cond":[]},{"kind":"text","text":"וְלִירוּשָׁלַיִם עִירְךָ בְּרַחֲמִים תָּשׁוּב וְתִשְׁכֹּן בְּתוֹכָהּ כַּאֲשֶׁר דִּבַּרְתָּ, וּבְנֵה אוֹתָהּ בְּקָרוֹב בְּיָמֵינוּ בִּנְיָן עוֹלָם, וְכִסֵּא דָוִד עַבְדְּךָ מְהֵרָה לְתוֹכָהּ תָּכִין. בָּרוּךְ אַתָּה יהוה, בּוֹנֵה יְרוּשָׁלָיִם.","cond":[]},{"kind":"text","text":"אֶת צֶמַח דָּוִד עַבְדְּךָ מְהֵרָה תַצְמִיחַ, וְקַרְנוֹ תָּרוּם בִּישׁוּעָתֶךָ, כִּי לִישׁוּעָתְךָ קִוִּינוּ כָּל הַיּוֹם (וּמְצַפִּים לִישׁוּעָה). בָּרוּךְ אַתָּה יהוה, מַצְמִיחַ קֶרֶן יְשׁוּעָה.","cond":[]},{"kind":"text","text":"אָב הָרַחֲמָן, שְׁמַע קוֹלֵנוּ יהוה אֱלֹהֵינוּ, חוּס וְרַחֵם עָלֵינוּ, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ, כִּי אֵל שׁוֹמֵעַ תְּפִלּוֹת וְתַחֲנוּנִים אָתָּה, וּמִלְּפָנֶיךָ מַלְכֵּנוּ, רֵיקָם אַל תְּשִׁיבֵנוּ. חָנֵּנוּ וַעֲנֵנוּ וּשְׁמַע תְּפִלָּתֵנוּ.","cond":[]},{"kind":"special","text":"וַעֲנֵנוּ בּוֹרֵא עוֹלָם בְּמִדַּת הָרַחֲמִים, בּוֹחֵר בְּעַמּוֹ יִשְׂרָאֵל לְהוֹדִיעַ גָדְלוֹ וְהַדְרַת כְּבוֹדוֹ, שׁוֹמֵעַ תְּפִלָּה תֵּן טַל וּמָטָר עַל פְּנֵי הָאֲדָמָה, וְתַשְׂבִּיעַ אֶת הָעוֹלָם כֻּלּוֹ מִטּוּבֶךָ, וּמַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ וּמֵעֹשֶׁר מַתְּנַת יָדֶךָ, שְׁמוֹר וְהַצֵּל שָׁנָה זוֹ מִכָּל דָּבָר רָע, וּמִכָּל מִינִי מַשְׁחִית, וּמִכָּל מִינֵי פֻּרְעָנֻיּוֹת, וַעֲשֵׂה לָהּ תִּקְוָה וְאַחֲרִית שָׁלוֹם, חוּס וְרַחֵם עָלֵינוּ וְעַל כָּל תְּבוּאָתֵנוּ וּפֵרוֹתֵינוּ, וּבָרְכֵנוּ בְּגִשְׁמֵי בְרָכָה וְנִזְכֶּה לְחַיִּים וָשֹׂבַע וְשָׁלוֹם, כַּשָּׁנִים הַטּוֹבוֹת, וְהָסֵר מִמֶּנּוּ דֶּבֶר וְחֶרֶב וְרָעָב, וְחַיָּה רָעָה וּשְׁבִי וּבִזָּה, וְיֵצֶר הָרָע וָחֳלָיִם רָעִים וְקָשִׁים, וּמְאוֹרָעוֹת רָעִים וְקָשִׁים, וּגְזֹר עָלֵינוּ גְּזֵרוֹת טוֹבוֹת מִלְּפָנֶיךָ, וְיִגֹּלוּ רָחֲמֶיךָ עַל מִדּוֹתֶיךָ, וְתִתְנַהֵג עִם בָּנֶיךָ בְּמִדַּת הָרַחֲמִים, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ.","cond":["vaanenu"]},{"kind":"text","text":"כִּי אַתָּה שׁוֹמֵעַ תְּפִלַּת כָּל פֶּה. בָּרוּךְ אַתָּה יהוה, שׁוֹמֵעַ תְּפִלָּה.","cond":[]},{"kind":"text","text":"רְצֵה יהוה אֱלֹהֵינוּ בְּעַמְּךָ יִשְׂרָאֵל וְלִתְפִלָּתָם שְׁעֵה, וְהָשֵׁב אֶת הָעֲבוֹדָה לִדְבִיר בֵּיתֶךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם, מְהֵרָה בְּאַהֲבָה תְקַבֵּל בְּרָצוֹן. וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּךָ.","cond":[]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּיעַ וְיֵרָאֶה וְיֵרָצֶה, וְיִשָּׁמַע וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵנוּ וּפִקְדוֹנֵנו וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךְ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָָל עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶיךָ, לִפְלֵטָה, לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["rh"]},{"kind":"special","text":"רֹאשׁ הַחֹדֶשׁ הַזֶּה.","cond":["rh"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ, וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["rh"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּיעַ וְיֵרָאֶה וְיֵרָצֶה, וְיִשָּׁמַע וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵנוּ וּפִקְדוֹנֵנו וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךְ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָָל עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶיךָ, לִפְלֵטָה, לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["sucot"]},{"kind":"special","text":"חַג הַסֻּכּוֹת הַזֶּה.","cond":["sucot"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ, וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["sucot"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּיעַ וְיֵרָאֶה וְיֵרָצֶה, וְיִשָּׁמַע וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵנוּ וּפִקְדוֹנֵנו וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךְ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָָל עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶיךָ, לִפְלֵטָה, לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["pesach"]},{"kind":"special","text":"חַג הַמַּצּוֹת הַזֶּה.","cond":["pesach"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ, וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["pesach"]},{"kind":"text","text":"וְתֶחֱזֶינָה עֵינֵינוּ בְּשׁוּבְךָ לְצִיּוֹן בְּרַחֲמִים. בָּרוּךְ אַתָּה יהוה, הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן.","cond":[]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שָׁאַתָּה הוּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ לְעוֹלָם וָעֵד. צוּר חַיֵּינוּ, מָגֵן יִשְׁעֵנוּ אַתָּה הוּא לְדוֹר וָדוֹר. נוֹדֶה לְּךָ וּנְסַפֵּר תְּהִלָּתֶךָ עַל חַיֵּינוּ הַמְּסוּרִים בְּיָדֶךָ, וְעַל נִשְׁמוֹתֵינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּיךָ שֶׁבְּכָל יוֹם עִמָּנוּ, וְעַל נִפְלְאוֹתֶיךָ וְטוֹבוֹתֶיךָ שֶׁבְּכָל עֵת, עֶרֶב וָבֹקֶר וְצָהֳרָיִם. הַטּוֹב כִּי לֹא כָלוּ רַחֲמֶיךָ, וְהַמְרַחֵם כִּי לֹא תַמּוּ חֲסָדֶיךָ, כִּי מֵעוֹלָם קִוִּינוּ לָךְ.","cond":[]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מַתִּתְיָהוּ בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְהַשְׁכִּיחָם תּוֹרָתֶךָ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנֶךָ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּטְמֵאִים בְּיַד טְהוֹרִים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, וּלְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמֶךָ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כֵּן בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ לְהוֹדוֹת וּלְהַלֵּל לְשִׁמְךָ הַגָּדוֹל. (נ\"א: וְקָבְעוּ שְׁמוֹנַת יָמִים אֵלּוּ בְּהַלֵּל וּבְהוֹדָאָה וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה.)","cond":["chanuka"]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים, מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ, וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ, וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְּרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ (, וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה).","cond":["purim"]},{"kind":"text","text":"וְעַל כֻּלָּם יִתְבָּרַךְ וְיִתְרוֹמַם וְיִתְנַשֵּׂא שִׁמְךָ מַלְכֵּנוּ תָּמִיד לְעוֹלָם וָעֶד.","cond":[]},{"kind":"special","text":"וּכְתֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶךָ.","cond":["ayt"]},{"kind":"text","text":"וְכֹל הַחַיִּים יוֹדוּךָ סֶלָה, וִיהַלְלוּ וִיבָרְכוּ אֶת שִׁמְךָ הַגָּדוֹל בֶּאֱמֶת לְעוֹלָם כִּי טוֹב, הָאֵל יְשׁוּעָתֵנוּ וְעֶזְרָתֵנוּ סֶלָה, הָאֵל הַטּוֹב. בָּרוּך אַתָּה יהוה, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת.","cond":[]},{"kind":"text","text":"שִׂים שָׁלוֹם טוֹבָה וּבְרָכָה, חַיִּים חֵן וָחֶסֶד וְרַחֲמִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל עַמֶּךָ. בָּרְכֵנוּ אָבִינוּ כֻּלָּנוּ כְּאֶחָד (יַחַד) בְּאוֹר פָּנֶיךָ, כִּי בְאוֹר פָּנֶיךָ נָתַתָּ לָּנוּ יהוה אֱלֹהֵינוּ תּוֹרַת חַיִּים וְאַהֲבַת חֶסֶד, וּצְדָקָה וּבְרָכָה וְרַחֲמִים וְחַיִּים וְשָׁלוֹם. וְטוֹב יִהְיֶה בְעֵינֶיךָ לְבָרְכֵנוּ וּלְבָרֵךְ אֶת כָּל עַמְּךָ יִשְׂרָאֵל בְּכָל עֵת וּבְכָל שָׁעָה בִּשְׁלוֹמֶךָ (בְּרֹב עֹז וְשָׁלוֹם).","cond":[]},{"kind":"special","text":"בְּסֵפֶר חַיִּים, בְּרָכָה וְשָׁלוֹם, וּפַרְנָסָה טוֹבָה, וּגְזֵרוֹת טוֹבוֹת, יְשׁוּעוֹת וְנֶחָמוֹת, נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ, אֲנַחְנוּ וְכָל עַמְּךָ בֵּית יִשְׂרָאֵל, לְחַיִּים טוֹבִים וּלְשָׁלוֹם.","cond":["ayt"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הַמְבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם.","cond":[]},{"kind":"text","text":"יִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ. יהוה צוּרִי וְגוֹאֲלִי:\nאֱלֹהַי, נְצֹר לְשׁוֹנִי מֵרָע וּשְׂפָתַי מִדַּבֵּר מִרְמָה, וְלִמְקַלְלַי נַפְשִׁי תִדֹּם, וְנַפְשִׁי כֶּעָפָר לַכֹּל תִּהְיֶה. פְּתַח לִבִּי בְּתוֹרָתֶךָ, וְאַחֲרֵי מִצְוׂתֶיךָ תִּרְדֹף נַפְשִׁי. וְכָל הַקָּמִים וְהַחוֹשְׁבִים עָלַי לְרָעָה, מְהֵרָה הָפֵר עֲצָתָם וְקַלְקֵל מַחֲשַׁבְתָּם.\n(יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁלֹּא תַעֲלֶה קִנְאַת אָדָם עָלַי וְלֹא קִנְאָתִי עַל אֲחֵרִים, וְשֶׁלֹּא אֶכְעוֹס הַיּוֹם וְשֶׁלֹּא אַכְעִיסֶךָ. וְתַצִּילֵנִי מִיֵּצֶר הָרָע, וְתֵן בְּלִבִּי הַכְנָעָה וַעֲנָוָה. מַלְכֵּנוּ וֵאלֹהֵינוּ אֱלוֹהַּ כָּל בָּשָׂר, יַחֵד שִׁמְךָ בְּעוֹלָמֶךָ, בְּנֵה עִירֶךָ, יַסֵּד בֵּיתֶךָ וְשַׁכְלֵל הֵיכָלֶךָ, וְקַבֵּץ קִבּוּץ גָלֻיּוֹת וּפְדֵה צֹאנֶךָ וְשַׂמַּח עָדָתֶךָ.)\nעֲשֵׂה לְמַעַן שְׁמֶךָ, עֲשֵׂה לְמַעַן יְמִינֶךָ, עֲשֵׂה לְמַעַן תּוֹרָתֶךָ, עֲשֵׂה לְמַעַן קְדֻשָּׁתֶךָ. לְמַעַן יֵחָלְצוּן יְדִידֶיךָ הוֹשִׁיעָה יְמִינְךָ וַעֲנֵנִי:\nיִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:","cond":[]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁיִּבָּנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵינוּ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתֶךָ, וְשָׁם נַעֲבָדְךָ בְּיִרְאָה כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמוֹנִיּוֹת. וְעָרְבָה לַיהוה מִנְחַת יְהוּדָה וִירוּשָׁלָיִם כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמֹנִיּוֹת:","cond":[]},{"kind":"header","text":"חזרת הש\"ץ","cond":[]},{"kind":"instruction","text":"חזרת הש\"ץ","cond":[]},{"kind":"text","text":"אֲדֹנָי, שְׂפָתַי תִּפְתָּח, וּפִי יַגִּיד תְּהִלָּתֶךָ:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק, וֵאלֹהֵי יַעֲקֹב, הָאֵל הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, וְקוֹנֵה הַכֹּל, וְזוֹכֵר חַסְדֵי אָבוֹת, וּמֵבִיא גוֹאֵל לִבְנֵי בְנֵיהֶם לְמַעַן שְׁמוֹ בְּאַהֲבָה.","cond":[]},{"kind":"special","text":"זָכְרֵנוּ לְחַיִּים, מֶלֶךְ חָפֵץ בַּחַיִּים, וְכָתְבֵנוּ בְּסֵפֶר הַחַיִּים, לְמַעַנְךָ אֱלֹהִים חַיִּים.","cond":["ayt"]},{"kind":"text","text":"מֶלֶךְ עוֹזֵר וּמוֹשִׁיעַ וּמָגֵן. בָּרוּךְ אַתָּה יהוה, מָגֵן אַבְרָהָם.","cond":[]},{"kind":"text","text":"אַתָּה גִּבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֵּה מֵתִים אַתָּה רַב לְהוֹשִׁיעַ,","cond":[]},{"kind":"summer","text":"מוֹרִיד הַטָּל,","cond":["summerTal"]},{"kind":"winter","text":"מַשִּׁיב הָרוּחַ וּמוֹרִיד הַגֶּשֶׁם,","cond":["winterTal"]},{"kind":"text","text":"מְכַלְכֵּל חַיִּים בְּחֶסֶד, מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים, סוֹמֵךְ נוֹפְלִים, וְרוֹפֵא חוֹלִים וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמוּנָתוֹ לִישֵׁנֵי עָפָר. מִי כָמוֹךָ בַּעַל גְּבוּרוֹת וּמִי דּוֹמֶה לָךְ, מֶלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִיחַ יְשׁוּעָה.","cond":[]},{"kind":"special","text":"מִי כָמוֹךָ אַב הָרַחֲמָן, זוֹכֵר יְצוּרָיו לְחַיִּים בְּרַחֲמִים.","cond":["ayt"]},{"kind":"text","text":"וְנֶאֱמָן אַתָּה לְהַחֲיוֹת מֵתִים. בָּרוּךְ אַתָּה יהוה, מְחַיֵּה הַמֵּתִים.","cond":[]},{"kind":"header","text":"קדושה","cond":[]},{"kind":"instruction","text":"קדושה בחזרת הש\"ץ:","cond":[]},{"kind":"text","text":"נַקְדִּישָׁךְ וְנַעֲרִיצָךְ כְּנֹעַם שִׂיחַ סוֹד שַׂרְפֵי קֹדֶשׁ הַמְשַׁלְּשִׁים לְךָ קְדֻשָּׁה, כַּכָּתוּב עַל יַד נְבִיאֶךָ: וְקָרָא זֶה אֶל זֶה וְאָמַר:\nקו\"ח: קָדוֹשׁ, קָדוֹשׁ, קָדוֹשׁ יהוה צְבָאוֹת, מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ:\nחזן: לְעֻמָּתָם מְשַׁבְּחִים וְאוֹמְרִים:\nקו\"ח: בָּרוּךְ כְּבוֹד יהוה מִמְּקוֹמוֹ:\nחזן: וּבְדִבְרֵי קָדְשְׁךָ כָּתוּב לֵאמֹר:\nקו\"ח: יִמְלֹך יהוה לְעוֹלָם, אֱלֹהַיִך צִיּוֹן לְדֹר וָדֹר, הַלְלוּיָהּ:","cond":[]},{"kind":"text","text":"אַתָּה קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ וּקְדוֹשִׁים בְּכָל יוֹם יְהַלְלוּךָ סֶּלָה, כִּי אֵל מֶלֶךְ גָּדוֹל וְקָדוֹשׁ אָתָּה.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הָאֵל הַקָּדוֹשׁ.","cond":["noayt"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יהוה, הַמֶּלֶךְ הַקָּדוֹשׁ.","cond":["ayt"]},{"kind":"text","text":"אַתָּה חוֹנֵן לְאָדָם דַּעַת וּמְלַמֵּד לֶאֱנוֹשׁ בִּינָה.","cond":[]},{"kind":"text","text":"חָנֵּנוּ מִאִתְּךָ חָכְמָה בִּינָה וָדָעַת","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, חוֹנֵן הַדָּעַת.","cond":[]},{"kind":"text","text":"הֲשִׁיבֵנוּ אָבִינוּ לְתוֹרָתֶךָ, וְקָרְבֵנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶך, וְהַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ. בָּרוּךְ אַתָּה יהוה, הָרוֹצֶה בִּתְשׁוּבָה.","cond":[]},{"kind":"text","text":"סְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ, כִּי אֵל טוֹב וְסַלָּח אָתָּה. בָּרוּךְ אַתָּה יהוה, חַנּוּן הַמַּרְבֶּה לִסְלֹחַ.","cond":[]},{"kind":"text","text":"רְאֵה נָא בְעָנְיֵנוּ, וְרִיבָה רִיבֵנוּ, וּגְאָלֵנוּ גְאֻלָּה שְׁלֵמָה מְהֵרָה לְמַעַן שְׁמֶךָ, כִּי אֵל גּוֹאֵל חָזָק אָתָּה. בָּרוּךְ אַתָּה יהוה, גּוֹאֵל יִשְׂרָאֵל.","cond":[]},{"kind":"instruction","text":"בתענית צבור החזן אומר:","cond":["taanit"]},{"kind":"special","text":"עֲנֵנוּ יהוה עֲנֵנוּ בְּיוֹם צוֹם תַּעֲנִיתֵנוּ, כִּי בְצָרָה גְדוֹלָה אֲנָחְנוּ. אַל תֵּפֶן אֶל רִשְׁעֵנוּ, וְאַל תַּסְתֵּר פָּנֶיךָ מִמֶּנּוּ, וְאַל תִּתְעַלַּם מִתְּחִנָּתֵנוּ. הֱיֵה נָא קָרוֹב לְשַׁוְעָתֵנוּ, יְהִי נָא חַסְדְּךָ לְנַחֲמֵנוּ, טֶרֶם נִקְרָא אֵלֶיךָ עֲנֵנוּ, כַּדָּבָר שֶׁנֶּאֱמַר: וְהָיָה טֶרֶם יִקְרָאוּ וַאֲנִי אֶעֱנֶה, עוֹד הֵם מְדַבְּרִים וַאֲנִי אֶשְׁמָע: כִּי אַתָּה יהוה הָעוֹנֶה בְּעֵת צָרָה, פּוֹדֶה וּמַצִּיל בְּכָל עֵת צָרָה וְצוּקָה. בָּרוּךְ אַתָּה יהוה, הָעוֹנֶה לְעַמּוֹ יִשְׂרָאֵל בְּעֵת צָרָה.","cond":["taanit"]},{"kind":"text","text":"רְפָאֵנוּ יהוה וְנֵרָפֵא, הוֹשִׁיעֵנוּ וְנִוָּשֵׁעָה כִּי תְהִלָּתֵנוּ אָתָּה, וְהַעֲלֵה (אֲרוּכָה וּמַרְפֵּא לְכָל תַּחֲלוּאֵינוּ וּלְכָל מַכְאוֹבֵינוּ) רְפוּאָה שְׁלֵמָה לְכָל מַכּוֹתֵינוּ. כִּי אֵל מֶלֶךְ רוֹפֵא נֶאֱמָן וְרַחֲמָן אָתָּה. בָּרוּךְ אַתָּה יהוה, רוֹפֵא חוֹלֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"בָּרֵך עָלֵינוּ יהוה אֱלֹהֵינוּ אֶת הַשָּׁנָה הַזֹּאת וְאֶת כָּל מִינֵי תְבוּאָתָהּ לְטוֹבָה, וְתֵן","cond":[]},{"kind":"summer","text":"בְּרָכָה","cond":["summerBracha"]},{"kind":"winter","text":"טַל וּמָטָר לִבְרָכָה","cond":["winterBracha"]},{"kind":"text","text":"עַל פְּנֵי הָאֲדָמָה וְשַׂבְּעֵנוּ מִטּוּבָהּ, וּבָרֵךְ שְׁנָתֵנוּ כַּשָּׁנִים הַטּוֹבוֹת לִבְרָכָה. כִּי אֵל טוֹב וּמֵטִיב אַתָּה וּמְבָרֵךְ הַשָּׁנִים. בָּרוּךְ אַתָּה יהוה, מְבָרֵךְ הַשָּׁנִים.","cond":[]},{"kind":"text","text":"תְּקַע בְּשׁוֹפָר גָּדוֹל לְחֵרוּתֵנוּ וְשָׂא נֵס לְקַבֵּץ גָּלֻיּוֹתֵינוּ, וְקַבְּצֵנוּ יַחַד מְהֵרָה מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ לְאַרְצֵנוּ. בָּרוּךְ אַתָּה יהוה, מְקַבֵּץ נִדְחֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"הָשִׁיבָה שׁוֹפְטֵינוּ כְּבָרִאשׁוֹנָה וְיוֹעֲצֵינוּ כְּבַתְּחִלָּה, וְהָסֵר מִמֶּנּוּ יָגוֹן וַאֲנָחָה, וּמְלֹךְ עָלֵינוּ מְהֵרָה אַתָּה יהוה לְבַדְּךָ בְּחֶסֶד וּבְרַחֲמִים, בְּצֶדֶק וּבְמִשְׁפָט.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, מֶלֶךְ אוֹהֵב צְדָקָה וּמִשְׁפָּט.","cond":["noayt"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יהוה, הַמֶּלֶךְ הַמִּשְׁפָּט.","cond":["ayt"]},{"kind":"text","text":"וְלַמַּלְשִׁינִים אַל תְּהִי תִקְוָה, וְכָל הַמִּינִים כְּרֶגַע יֹאבֵדוּ. וְכָל אוֹיְבֵי עַמְּךָ מְהֵרָה יִכָּרֵתוּ, וְהַזֵּדִים מְהֵרָה תְעַקֵּר וּתְשַׁבֵּר וּתְמַגֵּר וּתְכַלֵּם וְתַשְׁפִּילֵם וְתַכְנִיעֵם בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יהוה, שׁוֹבֵר אוֹיְבִים וּמַכְנִיעַ זֵדִים.","cond":[]},{"kind":"text","text":"עַל הַצַּדִּיקִים וְעַל הַחֲסִידִים, וְעַל זִקְנֵי שְׁאֵרִית עַמְּךָ בֵּית יִשְׂרָאֵל, וְעַל פְּלֵיטַת בֵּית סוֹפרֵיהֶם, וְעַל גֵּרֵי הַצֶדֶק וְעָלֵינוּ, יֶהֱמוּ נָא רַחֲמֶיךָ יהוה אֱלֹהֵינוּ, וְתֵן שָׂכָר טוֹב לְכָל הַבּוֹטְחִים בְּשִׁמְךָ בֶּאֱמֶת, וְשִׂים חֶלְקֵנוּ עִמָּהֶם וּלְעוֹלָם לֹא נֵבוֹשׁ כִּי בְךָ בָטָחְנוּ וְעַל חַסְדְּךָ הַגָּדוֹל בֶּאֱמֶת (וּבְתָמִים) נִשְׁעַנּוּ. בָּרוּךְ אַתָּה יהוה, מִשְׁעָן וּמִבְטָח לַצַּדִּיקִים.","cond":[]},{"kind":"text","text":"וְלִירוּשָׁלַיִם עִירְךָ בְּרַחֲמִים תָּשׁוּב וְתִשְׁכֹּן בְּתוֹכָהּ כַּאֲשֶׁר דִּבַּרְתָּ, וּבְנֵה אוֹתָהּ בְּקָרוֹב בְּיָמֵינוּ בִּנְיָן עוֹלָם, וְכִסֵּא דָוִד עַבְדְּךָ מְהֵרָה לְתוֹכָהּ תָּכִין. בָּרוּךְ אַתָּה יהוה, בּוֹנֵה יְרוּשָׁלָיִם.","cond":[]},{"kind":"text","text":"אֶת צֶמַח דָּוִד עַבְדְּךָ מְהֵרָה תַצְמִיחַ, וְקַרְנוֹ תָּרוּם בִּישׁוּעָתֶךָ, כִּי לִישׁוּעָתְךָ קִוִּינוּ כָּל הַיּוֹם (וּמְצַפִּים לִישׁוּעָה). בָּרוּךְ אַתָּה יהוה, מַצְמִיחַ קֶרֶן יְשׁוּעָה.","cond":[]},{"kind":"text","text":"אָב הָרַחֲמָן, שְׁמַע קוֹלֵנוּ יהוה אֱלֹהֵינוּ, חוּס וְרַחֵם עָלֵינוּ, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ, כִּי אֵל שׁוֹמֵעַ תְּפִלּוֹת וְתַחֲנוּנִים אָתָּה, וּמִלְּפָנֶיךָ מַלְכֵּנוּ, רֵיקָם אַל תְּשִׁיבֵנוּ. חָנֵּנוּ וַעֲנֵנוּ וּשְׁמַע תְּפִלָּתֵנוּ.","cond":[]},{"kind":"special","text":"וַעֲנֵנוּ בּוֹרֵא עוֹלָם בְּמִדַּת הָרַחֲמִים, בּוֹחֵר בְּעַמּוֹ יִשְׂרָאֵל לְהוֹדִיעַ גָדְלוֹ וְהַדְרַת כְּבוֹדוֹ, שׁוֹמֵעַ תְּפִלָּה תֵּן טַל וּמָטָר עַל פְּנֵי הָאֲדָמָה, וְתַשְׂבִּיעַ אֶת הָעוֹלָם כֻּלּוֹ מִטּוּבֶךָ, וּמַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ וּמֵעֹשֶׁר מַתְּנַת יָדֶךָ, שְׁמוֹר וְהַצֵּל שָׁנָה זוֹ מִכָּל דָּבָר רָע, וּמִכָּל מִינִי מַשְׁחִית, וּמִכָּל מִינֵי פֻּרְעָנֻיּוֹת, וַעֲשֵׂה לָהּ תִּקְוָה וְאַחֲרִית שָׁלוֹם, חוּס וְרַחֵם עָלֵינוּ וְעַל כָּל תְּבוּאָתֵנוּ וּפֵרוֹתֵינוּ, וּבָרְכֵנוּ בְּגִשְׁמֵי בְרָכָה וְנִזְכֶּה לְחַיִּים וָשֹׂבַע וְשָׁלוֹם, כַּשָּׁנִים הַטּוֹבוֹת, וְהָסֵר מִמֶּנּוּ דֶּבֶר וְחֶרֶב וְרָעָב, וְחַיָּה רָעָה וּשְׁבִי וּבִזָּה, וְיֵצֶר הָרָע וָחֳלָיִם רָעִים וְקָשִׁים, וּמְאוֹרָעוֹת רָעִים וְקָשִׁים, וּגְזֹר עָלֵינוּ גְּזֵרוֹת טוֹבוֹת מִלְּפָנֶיךָ, וְיִגֹּלוּ רָחֲמֶיךָ עַל מִדּוֹתֶיךָ, וְתִתְנַהֵג עִם בָּנֶיךָ בְּמִדַּת הָרַחֲמִים, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ.","cond":["vaanenu"]},{"kind":"text","text":"כִּי אַתָּה שׁוֹמֵעַ תְּפִלַּת כָּל פֶּה. בָּרוּךְ אַתָּה יהוה, שׁוֹמֵעַ תְּפִלָּה.","cond":[]},{"kind":"text","text":"רְצֵה יהוה אֱלֹהֵינוּ בְּעַמְּךָ יִשְׂרָאֵל וְלִתְפִלָּתָם שְׁעֵה, וְהָשֵׁב אֶת הָעֲבוֹדָה לִדְבִיר בֵּיתֶךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם, מְהֵרָה בְּאַהֲבָה תְקַבֵּל בְּרָצוֹן. וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּךָ.","cond":[]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּיעַ וְיֵרָאֶה וְיֵרָצֶה, וְיִשָּׁמַע וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵנוּ וּפִקְדוֹנֵנו וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךְ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָָל עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶיךָ, לִפְלֵטָה, לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["rh"]},{"kind":"special","text":"רֹאשׁ הַחֹדֶשׁ הַזֶּה.","cond":["rh"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ, וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["rh"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּיעַ וְיֵרָאֶה וְיֵרָצֶה, וְיִשָּׁמַע וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵנוּ וּפִקְדוֹנֵנו וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךְ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָָל עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶיךָ, לִפְלֵטָה, לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["sucot"]},{"kind":"special","text":"חַג הַסֻּכּוֹת הַזֶּה.","cond":["sucot"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ, וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["sucot"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּיעַ וְיֵרָאֶה וְיֵרָצֶה, וְיִשָּׁמַע וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵנוּ וּפִקְדוֹנֵנו וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךְ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָָל עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶיךָ, לִפְלֵטָה, לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["pesach"]},{"kind":"special","text":"חַג הַמַּצּוֹת הַזֶּה.","cond":["pesach"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ, וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["pesach"]},{"kind":"text","text":"וְתֶחֱזֶינָה עֵינֵינוּ בְּשׁוּבְךָ לְצִיּוֹן בְּרַחֲמִים. בָּרוּךְ אַתָּה יהוה, הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן.","cond":[]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שָׁאַתָּה הוּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ לְעוֹלָם וָעֵד. צוּר חַיֵּינוּ, מָגֵן יִשְׁעֵנוּ אַתָּה הוּא לְדוֹר וָדוֹר. נוֹדֶה לְּךָ וּנְסַפֵּר תְּהִלָּתֶךָ עַל חַיֵּינוּ הַמְּסוּרִים בְּיָדֶךָ, וְעַל נִשְׁמוֹתֵינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּיךָ שֶׁבְּכָל יוֹם עִמָּנוּ, וְעַל נִפְלְאוֹתֶיךָ וְטוֹבוֹתֶיךָ שֶׁבְּכָל עֵת, עֶרֶב וָבֹקֶר וְצָהֳרָיִם. הַטּוֹב כִּי לֹא כָלוּ רַחֲמֶיךָ, וְהַמְרַחֵם כִּי לֹא תַמּוּ חֲסָדֶיךָ, כִּי מֵעוֹלָם קִוִּינוּ לָךְ.","cond":[]},{"kind":"header","text":"מודים דרבנן","cond":[]},{"kind":"instruction","text":"מודים דרבנן:","cond":[]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שָׁאַתָּה הוּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי כָל בָּשָׂר, יוֹצְרֵנוּ יוֹצֵר בְּרֵאשִׁית, בְּרָכוֹת וְהוֹדָאוֹת לְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ עַל שֶׁהֶחֱיִיתָנוּ וְקִיַּמְתָּנוּ. כֵּן תְּחַיֵּנוּ וּתְקַיְּמֵנוּ, וְתֶאֱסוֹף גָּלֻיּוֹתֵינוּ לְחַצְרוֹת קָדְשֶׁךָ, לִשְׁמוֹר חֻקֶּיךָ, וְלַעֲשׂוֹת רְצוֹנֶךָ, וּלְעָבְדְךָ בְּלֵבָב שָׁלֵם, עַל שֶׁאֲנַחְנוּ מוֹדִים לָךְ. בָּרוּךְ אֵל הַהוֹדָאוֹת.","cond":[]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מַתִּתְיָהוּ בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְהַשְׁכִּיחָם תּוֹרָתֶךָ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנֶךָ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּטְמֵאִים בְּיַד טְהוֹרִים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, וּלְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמֶךָ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כֵּן בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ לְהוֹדוֹת וּלְהַלֵּל לְשִׁמְךָ הַגָּדוֹל. (נ\"א: וְקָבְעוּ שְׁמוֹנַת יָמִים אֵלּוּ בְּהַלֵּל וּבְהוֹדָאָה וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה.)","cond":["chanuka"]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים, מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ, וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ, וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְּרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ (, וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה).","cond":["purim"]},{"kind":"text","text":"וְעַל כֻּלָּם יִתְבָּרַךְ וְיִתְרוֹמַם וְיִתְנַשֵּׂא שִׁמְךָ מַלְכֵּנוּ תָּמִיד לְעוֹלָם וָעֶד.","cond":[]},{"kind":"special","text":"וּכְתֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶךָ.","cond":["ayt"]},{"kind":"text","text":"וְכֹל הַחַיִּים יוֹדוּךָ סֶלָה, וִיהַלְלוּ וִיבָרְכוּ אֶת שִׁמְךָ הַגָּדוֹל בֶּאֱמֶת לְעוֹלָם כִּי טוֹב, הָאֵל יְשׁוּעָתֵנוּ וְעֶזְרָתֵנוּ סֶלָה, הָאֵל הַטּוֹב. בָּרוּך אַתָּה יהוה, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת.","cond":[]},{"kind":"header","text":"ברכת כהנים","cond":["noTishaaBeav"]},{"kind":"instruction","text":"ברכת כהנים לחזרת הש\"ץ:\n\nאם לא עלו כהנים לדוכן הש\"ץ אומר או\"א (נמצא בהמשך).\n\nאם עלו שני כהנים לדוכן קוראים להם - כֹּהֲנִים:\n\nהכהנים מברכים:","cond":["noTishaaBeav"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בִּקְדֻשָּׁתוֹ שֶׁל אַהֲרֹן, וְצִוָּנוּ לְבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בְּאַהֲבָה.\n\nיְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ:\nיָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ:\nיִשָּׂא יהוה פָּנָיו אֵלֶיךָ וְיָשֵׂם לְךָ שָׁלוֹם:","cond":["noTishaaBeav"]},{"kind":"instruction","text":"הקהל אומר:","cond":["noTishaaBeav"]},{"kind":"text","text":"אַדִּיר בַּמָּרוֹם שׁוֹכֵן בִּגְבוּרָה, אַתָּה שָׁלוֹם וְשִׁמְךָ שָׁלוֹם. יְהִי רָצוֹן שֶׁתָּשִׂים עָלֵינוּ וְעַל כָּל עַמְּךָ בֵּית יִשְׂרָאֵל חַיִּים וּבְרָכָה לְמִשְׁמֶרֶת שָׁלוֹם.","cond":["noTishaaBeav"]},{"kind":"instruction","text":"הכהנים אומרים","cond":["noTishaaBeav"]},{"kind":"text","text":"רִבּוֹנוֹ שֶׁל עוֹלָם, עָשִׂינוּ מַה שֶּׁגָּזַרְתָּ עָלֵינוּ, אַף אַתָּה עֲשֵׂה עִמָּנוּ כְּמוֹ שֶׁהִבְטַחְתָּנוּ: הַשְׁקִיפָה מִמְּעוֹן קָדְשְׁךָ מִן הַשָּׁמַיִם, וּבָרֵךְ אֶת עַמְּךָ אֶת יִשְׂרָאֵל, וְאֵת הָאֲדָמָה אֲשֶׁר נָתַתָּה לָנוּ, כַּאֲשֶׁר נִשְׁבַּעְתָּ לַאֲבֹתֵינוּ, אֶרֶץ זָבַת חָלָב וּדְבָשׁ:","cond":["noTishaaBeav"]},{"kind":"instruction","text":"אם לא עלו כהנים לדוכן הש\"ץ אומר:","cond":["noTishaaBeav"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, בָּרְכֵנוּ בַּבְּרָכָה הַמְשֻׁלֶּשֶׁת בַּתּוֹרָה הַכְּתוּבָה עַל יְדֵי מֹשֶׁה עַבְדֶּךָ, הָאֲמוּרָה מִפִּי אַהֲרֹן וּבָנָיו כֹּהֲנִים עַם קְדוֹשֶׁךָ, כָּאָמוּר: יְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ: יָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ: יִשָּׂא יהוה פָּנָיו אֵלֶיךָ וְיָשֵׂם לְךָ שָׁלוֹם:","cond":["noTishaaBeav"]},{"kind":"text","text":"שִׂים שָׁלוֹם טוֹבָה וּבְרָכָה, חַיִּים חֵן וָחֶסֶד וְרַחֲמִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל עַמֶּךָ. בָּרְכֵנוּ אָבִינוּ כֻּלָּנוּ כְּאֶחָד (יַחַד) בְּאוֹר פָּנֶיךָ, כִּי בְאוֹר פָּנֶיךָ נָתַתָּ לָּנוּ יהוה אֱלֹהֵינוּ תּוֹרַת חַיִּים וְאַהֲבַת חֶסֶד, וּצְדָקָה וּבְרָכָה וְרַחֲמִים וְחַיִּים וְשָׁלוֹם. וְטוֹב יִהְיֶה בְעֵינֶיךָ לְבָרְכֵנוּ וּלְבָרֵךְ אֶת כָּל עַמְּךָ יִשְׂרָאֵל בְּכָל עֵת וּבְכָל שָׁעָה בִּשְׁלוֹמֶךָ (בְּרֹב עֹז וְשָׁלוֹם).","cond":[]},{"kind":"special","text":"בְּסֵפֶר חַיִּים, בְּרָכָה וְשָׁלוֹם, וּפַרְנָסָה טוֹבָה, וּגְזֵרוֹת טוֹבוֹת, יְשׁוּעוֹת וְנֶחָמוֹת, נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ, אֲנַחְנוּ וְכָל עַמְּךָ בֵּית יִשְׂרָאֵל, לְחַיִּים טוֹבִים וּלְשָׁלוֹם.","cond":["ayt"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הַמְבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם.","cond":[]},{"kind":"text","text":"יִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:","cond":[]},{"kind":"header","text":"סדר נטילת לולב","cond":["sucot"]},{"kind":"instruction","text":"סדר נטילת לולב\n\nיקח את הלולב, ההדסים והערבות בידו הימנית כאשר שדרת הלולב תפנה אליו, והם מצביעים למעלה \"כדרך גידולם\". את האתרוג ייקח בידו השמאלית ויחזיקו הפוך, כלומר העוקץ (מיקום חיבורו לעץ) מופנה כלפי מעלה.","cond":["sucot"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ עַל נְטִילַת לוּלָב.","cond":["sucot"]},{"kind":"text","text":"בָּרוּךְ אַָתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁהֶחֱיָנוּ וְקִיְּמָנוּ וְהִגִּיעָנוּ לַזְּמַן הַזֶּה.","cond":["sucot","lulav_shehecheyanu"]},{"kind":"instruction","text":"לאחר הברכה הופכים את האתרוג ומחזיקים אותו כדרך גידולו כך שהפיטם פונה כלפי מעלה. לאחר מכן מקרבים את הלולב והאתרוג יחד ומנענעים אותם לכל הכיוונים.","cond":["sucot"]},{"kind":"header","text":"הלל","cond":["hallel"]},{"kind":"instruction","text":"הלל","cond":["hallel"]},{"kind":"instruction","text":"הנוהגים להניח תפילין בחול המועד יחלצו את התפילין לפני קריאת ההלל. שליח הציבור יחלצם לאחר אמירת הקדיש שלאחר הלל (משנ\"ב כ\"ה ס\"ק ס'). לאחר מכן אין מניחים שוב את התפילין, וכן לא מניחים תפילין דרבינו תם.","cond":["hallel","pesach"]},{"kind":"instruction","text":"הנוהגים להניח תפילין בחול המועד יחלצו את התפילין לפני קריאת ההלל. שליח הציבור גם כן יחלוץ כאן את התפילין בזמן שהקהל מתעסק בארבעת המינים (משנ\"ב כ\"ה ס\"ק ס'). לאחר מכן אין מניחים שוב את התפילין, וכן לא מניחים תפילין דרבינו תם.","cond":["hallel","sucot"]},{"kind":"instruction","text":"יש המברכים על הלל ביום העצמאות וביום שחרור ירושלים ויש שאינם מברכים, ויש שאינם אומרים הלל כלל בימים אלה.","cond":["hallel","yerushalayim"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ לִקְרֹא אֶת הַהַלֵּל.","cond":["hallel"]},{"kind":"text","text":"הַלְלוּיָהּ, הַלְלוּ עַבְדֵי יהוה, הַלְלוּ אֶת שֵׁם יהוה: יְהִי שֵׁם יהוה מְבֹרָךְ מֵעַתָּה וְעַד עוֹלָם: מִמִּזְרַח שֶׁמֶשׁ עַד מְבוֹאוֹ מְהֻלָּל שֵׁם יהוה: רָם עַל כָּל גּוֹיִם יהוה, עַל הַשָּׁמַיִם כְּבוֹדוֹ: מִי כַּיהוה אֱלֹהֵינוּ הַמַּגְבִּיהִי לָשָׁבֶת: הַמַּשְׁפִּילִי לִרְאוֹת בַּשָּׁמַיִם וּבָאָרֶץ: מְקִימִי מֵעָפָר דָּל, מֵאַשְׁפֹּת יָרִים אֶבְיוֹן: לְהוֹשִׁיבִי עִם נְדִיבִים, עִם נְדִיבֵי עַמּוֹ: מוֹשִׁיבִי עֲקֶרֶת הַבַּיִת, אֵם הַבָּנִים שְׂמֵחָה הַלְלוּיָהּ:","cond":["hallel"]},{"kind":"text","text":"בְּצֵאת יִשְׂרָאֵל מִמִּצְרָיִם, בֵּית יַעֲקֹב מֵעַם לֹעֵז: הָיְתָה יְהוּדָה לְקָדְשׁוֹ, יִשְׂרָאֵל מַמְשְׁלוֹתָיו: הַיָּם רָאָה וַיָּנֹס, הַיַּרְדֵּן יִסֹּב לְאָחוֹר: הֶהָרִים רָקְדוּ כְאֵילִים, גְּבָעוֹת כִּבְנֵי צֹאן: מַה לְּךָ הַיָּם כִּי תָנוּס, הַיַּרְדֵּן תִּסֹּב לְאָחוֹר: הֶהָרִים תִּרְקְדוּ כְאֵילִים, גְּבָעוֹת כִּבְנֵי צֹאן: מִלִּפְנֵי אָדוֹן חוּלִי אָרֶץ, מִלִּפְנֵי אֱלוֹהַּ יַעֲקֹב: הַהֹפְכִי הַצּוּר אֲגַם מָיִם, חַלָּמִישׁ לְמַעְיְנוֹ מָיִם:","cond":["hallel"]},{"kind":"text","text":"לֹא לָנוּ, יהוה, לֹא לָנוּ, כִּי לְשִׁמְךָ תֵּן כָּבוֹד עַל חַסְדְּךָ עַל אֲמִתֶּךָ: לָמָּה יֹאמְרוּ הַגּוֹיִם אַיֵּה נָא אֱלֹהֵיהֶם: וֵאלֹהֵינוּ בַשָּׁמָיִם כֹּל אֲשֶׁר חָפֵץ עָשָׂה: עֲצַבֵּיהֶם כֶּסֶף וְזָהָב, מַעֲשֵׂה יְדֵי אָדָם: פֶּה לָהֶם וְלֹא יְדַבֵּרוּ, עֵינַיִם לָהֶם וְלֹא יִרְאוּ: אָזְנַיִם לָהֶם וְלֹא יִשְׁמָעוּ, אַף לָהֶם וְלֹא יְרִיחוּן: יְדֵיהֶם וְלֹא יְמִישׁוּן, רַגְלֵיהֶם וְלֹא יְהַלֵּכוּ, לֹא יֶהְגּוּ בִּגְרוֹנָם: כְּמוֹהֶם יִהְיוּ עֹשֵׂיהֶם, כֹּל אֲשֶׁר בֹּטֵחַ בָּהֶם: יִשְׂרָאֵל בְּטַח בַּיהוה, עֶזְרָם וּמָגִנָּם הוּא: בֵּית אַהֲרֹן בִּטְחוּ בַיהוה, עֶזְרָם וּמָגִנָּם הוּא: יִרְאֵי יהוה בִּטְחוּ בַיהוה, עֶזְרָם וּמָגִנָּם הוּא:","cond":["hallel","fullHallel"]},{"kind":"text","text":"יהוה זְכָרָנוּ יְבָרֵךְ, יְבָרֵךְ אֶת בֵּית יִשְׂרָאֵל, יְבָרֵךְ אֶת בֵּית אַהֲרֹן: יְבָרֵךְ יִרְאֵי יהוה, הַקְּטַנִּים עִם הַגְּדֹלִים: יֹסֵף יהוה עֲלֵיכֶם, עֲלֵיכֶם וְעַל בְּנֵיכֶם: בְּרוּכִים אַתֶּם לַיהוה, עֹשֵׂה שָׁמַיִם וָאָרֶץ: הַשָּׁמַיִם שָׁמַיִם לַיהוה, וְהָאָרֶץ נָתַן לִבְנֵי אָדָם: לֹא הַמֵּתִים יְהַלְלוּ יָהּ, וְלֹא כָּל יֹרְדֵי דוּמָה: וַאֲנַחְנוּ נְבָרֵךְ יָהּ מֵעַתָּה וְעַד עוֹלָם הַלְלוּיָהּ:","cond":["hallel"]},{"kind":"text","text":"אָהַבְתִּי כִּי יִשְׁמַע יהוה אֶת קוֹלִי תַּחֲנוּנָי: כִּי הִטָּה אָזְנוֹ לִי וּבְיָמַי אֶקְרָא: אֲפָפוּנִי חֶבְלֵי מָוֶת וּמְצָרֵי שְׁאוֹל מְצָאוּנִי, צָרָה וְיָגוֹן אֶמְצָא: וּבְשֵׁם יהוה אֶקְרָא, אָנָּה יהוה מַלְּטָה נַפְשִׁי: חַנּוּן יהוה וְצַדִּיק, וֵאלֹהֵינוּ מְרַחֵם: שֹׁמֵר פְּתָאיִם יהוה, דַּלּוֹתִי וְלִי יְהוֹשִׁיעַ: שׁוּבִי נַפְשִׁי לִמְנוּחָיְכִי כִּי יהוה גָּמַל עָלָיְכִי: כִּי חִלַּצְתָּ נַפְשִׁי מִמָּוֶת, אֶת עֵינִי מִן דִּמְעָה, אֶת רַגְלִי מִדֶּחִי: אֶתְהַלֵּךְ לִפְנֵי יהוה בְּאַרְצוֹת הַחַיִּים: הֶאֱמַנְתִּי כִּי אֲדַבֵּר אֲנִי עָנִיתִי מְאֹד: אֲנִי אָמַרְתִּי בְחָפְזִי כָּל הָאָדָם כֹּזֵב:","cond":["hallel","fullHallel"]},{"kind":"text","text":"מָה אָשִׁיב לַיהוה, כָּל תַּגְמוּלוֹהִי עָלָי: כּוֹס יְשׁוּעוֹת אֶשָּׂא, וּבְשֵׁם יהוה אֶקְרָא: נְדָרַי לַיהוה אֲשַׁלֵּם, נֶגְדָה נָּא לְכָל עַמּוֹ: יָקָר בְּעֵינֵי יהוה הַמָּוְתָה לַחֲסִידָיו: אָנָּה יהוה כִּי אֲנִי עַבְדֶּךָ, אֲנִי עַבְדְּךָ בֶּן אֲמָתֶךָ, פִּתַּחְתָּ לְמוֹסֵרָי: לְךָ אֶזְבַּח זֶבַח תּוֹדָה, וּבְשֵׁם יהוה אֶקְרָא: נְדָרַי לַיהוה אֲשַׁלֵּם, נֶגְדָה נָּא לְכָל עַמּוֹ: בְּחַצְרוֹת בֵּית יהוה, בְּתוֹכֵכִי יְרוּשָׁלָיִם הַלְלוּיָהּ:","cond":["hallel"]},{"kind":"text","text":"הַלְלוּ אֶת יהוה כָּל גּוֹיִם, שַׁבְּחוּהוּ כָּל הָאֻמִּים: כִּי גָבַר עָלֵינוּ חַסְדּוֹ, וֶאֱמֶת יהוה לְעוֹלָם הַלְלוּיָהּ:","cond":["hallel"]},{"kind":"instruction","text":"ארבעה פסוקים אלה אומר החזן פסוק פסוק והקהל עונה \"הוֹדוּ לַה'...\". ויש האומרים בלחש יחד עם החזן את הפסוק שהוא אומר. ויש בכך מנהגים שונים.","cond":["hallel"]},{"kind":"text","text":"הוֹדוּ לַיהוה כִּי טוֹב, כִּי לְעוֹלָם חַסְדּוֹ:\nיֹאמַר נָא יִשְׂרָאֵל, כִּי לְעוֹלָם חַסְדּוֹ:\nיֹאמְרוּ נָא בֵית אַהֲרֹן, כִּי לְעוֹלָם חַסְדּוֹ:\nיֹאמְרוּ נָא יִרְאֵי יהוה, כִּי לְעוֹלָם חַסְדּוֹ:","cond":["hallel"]},{"kind":"text","text":"מִן הַמֵּצַר קָרָאתִי יָהּ, עָנָנִי בַמֶּרְחָב יָהּ: יהוה לִי לֹא אִירָא, מַה יַּעֲשֶׂה לִי אָדָם: יהוה לִי בְּעֹזְרָי, וַאֲנִי אֶרְאֶה בְשֹׂנְאָי: טוֹב לַחֲסוֹת בַּיהוה מִבְּטֹחַ בָּאָדָם: טוֹב לַחֲסוֹת בַּיהוה מִבְּטֹחַ בִּנְדִיבִים: כָּל גּוֹיִם סְבָבוּנִי בְּשֵׁם יהוה כִּי אֲמִילַם: סַבּוּנִי גַם סְבָבוּנִי בְּשֵׁם יהוה כִּי אֲמִילַם: סַבּוּנִי כִדְבוֹרִים דֹּעֲכוּ כְּאֵשׁ קוֹצִים בְּשֵׁם יהוה כִּי אֲמִילַם: דַּחֹה דְחִיתַנִי לִנְפֹּל וַיהוה עֲזָרָנִי: עָזִּי וְזִמְרָת יָהּ וַיְהִי לִי לִישׁוּעָה: קוֹל רִנָּה וִישׁוּעָה בְּאָהֳלֵי צַדִּיקִים, יְמִין יהוה עֹשָׂה חָיִל: יְמִין יהוה רוֹמֵמָה, יְמִין יהוה עֹשָׂה חָיִל: לֹא אָמוּת כִּי אֶחְיֶה וַאֲסַפֵּר מַעֲשֵׂי יָהּ: יַסֹּר יִסְּרַנִּי יָּהּ וְלַמָּוֶת לֹא נְתָנָנִי: פִּתְחוּ לִי שַׁעֲרֵי צֶדֶק, אָבֹא בָם אוֹדֶה יָהּ: זֶה הַשַּׁעַר לַיהוה, צַדִּיקִים יָבֹאוּ בוֹ:","cond":["hallel"]},{"kind":"text","text":"אוֹדְךָ כִּי עֲנִיתָנִי וַתְּהִי לִי לִישׁוּעָה:\nאוֹדְךָ כִּי עֲנִיתָנִי וַתְּהִי לִי לִישׁוּעָה:\n\nאֶבֶן מָאֲסוּ הַבּוֹנִים, הָיְתָה לְרֹאשׁ פִּנָּה:\nאֶבֶן מָאֲסוּ הַבּוֹנִים, הָיְתָה לְרֹאשׁ פִּנָּה:\n\nמֵאֵת יהוה הָיְתָה זֹּאת, הִיא נִפְלָאת בְּעֵינֵינוּ:\nמֵאֵת יהוה הָיְתָה זֹּאת, הִיא נִפְלָאת בְּעֵינֵינוּ:\n\nזֶה הַיּוֹם עָשָׂה יהוה, נָגִילָה וְנִשְׂמְחָה בוֹ:\nזֶה הַיּוֹם עָשָׂה יהוה, נָגִילָה וְנִשְׂמְחָה בוֹ:","cond":["hallel"]},{"kind":"instruction","text":"פסוק \"אָנָּא יהוה הוֹשִׁיעָה נָּא, אָנָּא יהוה הַצְלִיחָה נָּא\" נחלק לשניים, ואומרים כל חלק פעמיים. נוהגים שהחזן אומר חלק והקהל חוזר אחריו.","cond":["hallel"]},{"kind":"text","text":"אָנָּא יהוה הוֹשִׁיעָה נָּא.\nאָנָּא יהוה הוֹשִׁיעָה נָּא.\n\nאָנָּא יהוה הַצְלִיחָה נָּא:\nאָנָּא יהוה הַצְלִיחָה נָּא:","cond":["hallel"]},{"kind":"text","text":"בָּרוּךְ הַבָּא בְּשֵׁם יהוה, בֵּרַכְנוּכֶם מִבֵּית יהוה:\nבָּרוּךְ הַבָּא בְּשֵׁם יהוה, בֵּרַכְנוּכֶם מִבֵּית יהוה:\n\nאֵל יהוה וַיָּאֶר לָנוּ אִסְרוּ חַג בַּעֲבֹתִים עַד קַרְנוֹת הַמִּזְבֵּחַ:\nאֵל יהוה וַיָּאֶר לָנוּ אִסְרוּ חַג בַּעֲבֹתִים עַד קַרְנוֹת הַמִּזְבֵּחַ:\n\nאֵלִי אַתָּה וְאוֹדֶךָּ, אֱלֹהַי אֲרוֹמְמֶךָּ:\nאֵלִי אַתָּה וְאוֹדֶךָּ, אֱלֹהַי אֲרוֹמְמֶךָּ:\n\nהוֹדוּ לַיהוה כִּי טוֹב, כִּי לְעוֹלָם חַסְדּוֹ:\nהוֹדוּ לַיהוה כִּי טוֹב, כִּי לְעוֹלָם חַסְדּוֹ:","cond":["hallel"]},{"kind":"text","text":"יְהַלְלוּךָ יהוה אֱלֹהֵינוּ עַל כָּל מַעֲשֶׂיךָ, וַחֲסִידֶיךָ צַדִּיקִים עוֹשֵׂי רְצוֹנֶךָ, וְכָל עַמְּךָ בֵּית יִשְׂרָאֵל בְּרִנָּה יוֹדוּ וִיבָרְכוּ וִישַׁבְּחוּ וִיפָאֲרוּ וִישׁוֹרְרוּ וִירוֹמְמוּ וְיַעֲרִיצוּ וְיַקְדִּישׁוּ וְיַמְלִיכוּ אֶת שִׁמְךָ מַלְכֵּנוּ תָּמִיד, כִּי לְךָ טוֹב לְהוֹדוֹת וּלְשִׁמְךָ נָאֶה לְזַמֵּר, כִּי מֵעוֹלָם וְעַד עוֹלָם אַתָּה אֵל. בָּרוּךְ אַתָּה יהוה, מֶלֶךְ מְהֻלָּל בַּתִּשְׁבָּחוֹת.","cond":["hallel"]},{"kind":"header","text":"הושענות","cond":["hallel","sucot"]},{"kind":"instruction","text":"הושענות","cond":["hallel","sucot"]},{"kind":"instruction","text":"מוציאים את כל ספרי התורה אל הבימה.","cond":["hallel","sucot","hoshanaraba"]},{"kind":"instruction","text":"מוציאים ספר תורה אל הבימה.","cond":["hallel","sucot","noHoshanaraba"]},{"kind":"instruction","text":"החזן אומר משפט משפט ואחריו הקהל:","cond":["hallel","sucot"]},{"kind":"text","text":"הוֹשַׁע נָא לְמַעַנְךָ אֱלֹהֵינוּ, הוֹשַׁע נָא.\nהוֹשַׁע נָא לְמַעַנְךָ בּוֹרְאֵנוּ, הוֹשַׁע נָא.\nהוֹשַׁע נָא לְמַעַנְךָ גּוֹאֲלֵנוּ, הוֹשַׁע נָא.\nהוֹשַׁע נָא לְמַעַנְךָ דּוֹרְשֵׁנוּ, הוֹשַׁע נָא.","cond":["hallel","sucot"]},{"kind":"instruction","text":"מתחילים להקיף את הבימה עם ארבעת המינים. אבל ומי שאין לו ארבעה מינים לא יקיף עם הציבור.","cond":["hallel","sucot"]},{"kind":"text","text":"=-=-","cond":["hallel","sucot"]},{"kind":"instruction","text":"מפסיקים להקיף את הבימה ואומרים:","cond":["hallel","sucot"]},{"kind":"text","text":"אֲנִי וָהוֹ הוֹשִׁיעָה נָּא.\n\nכְּהוֹשַׁעְתָּ אֵלִים בְּלוּד עִמָּךְ, בְּצֵאתְךָ לְיֵשַׁע עַמָּךְ, כֵּן הוֹשַׁע נָא.\nכְּהוֹשַׁעְתָּ גּוֹי וֵאלֹהִים, דְרוּשִׁים לְיֵשַׁע אֱלֹהִים, כֵּן הוֹשַׁע נָא.\nכְּהוֹשַׁעְתָּ הֲמוֹן צִבְאוֹת, וְעִמָּם מַלְאֲכֵי צְבָאוֹת, כֵּן הוֹשַׁע נָא.\nכְּהוֹשַׁעְתָּ זַכִּים מִבֵּית עֲבָדִים, חַנּוּן בְּיָדָם מַעֲבִידִים, כֵּן הוֹשַׁע נָא.\nכְּהוֹשַׁעְתָּ טְבוּעִים בְּצוּל גְּזָרִים, יְקָרְךָ עִמָּם מַעֲבִירִים, כֵּן הוֹשַׁע נָא.\nכְּהוֹשַׁעְתָּ כַּנָּה מְשׁוֹרֶרֶת וַיּוֹשַׁע, לְגוֹחָהּ מְצֻיֶּנֶת וַיִּוָּשַׁע, כֵּן הוֹשַׁע נָא.\nכְּהוֹשַׁעְתָּ מַאֲמַר \"וְהוֹצֵאתִי אֶתְכֶם\", נָקוּב \"וְהוּצֵאתִי אִתְּכֶם\", כֵּן הוֹשַׁע נָא.\nכְּהוֹשַׁעְתָּ סוֹבְבֵי מִזְבֵּחַ, עוֹמְסֵי עֲרָבָה לְהַקִּיף מִזְבֵּחַ, כֵּן הוֹשַׁע נָא.\nכְּהוֹשַׁעְתָּ פִּלְאֵי אָרוֹן כְּהֻפְשַׁע, צִעֵר פְּלֶשֶׁת בַּחֲרוֹן אַף וְנוֹשַׁע, כֵּן הוֹשַׁע נָא.\nכְּהוֹשַׁעְתָּ קְהִלּוֹת בָּבֶלָה שָׁלַחְתָּ, רַחוּם לְמַעֲנָם שֻׁלַּחְתָּ, כֵּן הוֹשַׁע נָא.\nכְּהוֹשַׁעְתָּ שְׁבוּת שִׁבְטֵי יַעֲקֹב, תָּשׁוּב וְתָשִׁיב שְׁבוּת אָהֳלֵי יַעֲקֹב וְהוֹשִׁיעָה נָּא.\nכְּהוֹשַׁעְתָּ שׁוֹמְרֵי מִצְוׂת וְחוֹכֵי יְשׁוּעוֹת, אֵל לְמוֹשָׁעוֹת, וְהוֹשִׁיעָה נָּא.\n\nאֲנִי וָהוֹ הוֹשִׁיעָה נָּא.","cond":["hallel","sucot"]},{"kind":"text","text":"הוֹשַׁע נָא תִּתְּנֵנוּ לְשֵׁם וְלִתְהִלָּה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּשִׁיבֵנוּ אֶל הַחֶבֶל וְאֶל הַנַּחֲלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּרוֹמְמֵנוּ לְמַעְלָה לְמַעְלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּקַבְּצֵנוּ לְבֵית הַתְּפִלָּה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תַּצִּיבֵנוּ כְּעֵץ עַל פַּלְגֵי מַיִם שְׁתוּלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תִּפְדֵּנוּ מִכָּל נֶגַע וּמַחֲלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּעַטְּרֵנוּ בְּאַהֲבָה כְלוּלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּשַׂמְּחֵנוּ בְּבֵית הַתְּפִלָּה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּנַהֲלֵנוּ עַל מֵי מְנוּחוֹת סֶלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּמַלְאֵנוּ חָכְמָה וְשִׂכְלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תַּלְבִּישֵׁנוּ עֹז וּגְדֻלָּה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תַּכְתִּירֵנוּ בְּכֶתֶר כְּלוּלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּיַשְּׁרֵנוּ בְּאֹרַח סְלוּלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תִּטָּעֵנוּ בְּיֹשֶׁר מְסִלָּה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּחָנֵּנוּ בְּרַחֲמִים וּבְחֶמְלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תַּזְכִּירֵנוּ בְּמִי זֹאת עוֹלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תּוֹשִׁיעֵנוּ לְקֵץ הַגְּאֻלָּה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּהַדְּרֵנוּ בְּזִיו הֲמוּלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תַּדְבִּיקֵנוּ כְּאֵזוֹר חֲתוּלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּגַדְּלֵנוּ בְּיָד הַגְּדוֹלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּבִיאֵנוּ לְבֵיתְךָ בְּרִנָּה וְצָהֳלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּאַדְּרֵנוּ בְּיֶשַׁע וְגִילָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּאַמְּצֵנוּ בְּרֶוַח וְהַצָּלָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּלַבְּבֵנוּ בְּבִנְיַן עִירְךָ כְּבַתְּחִלָּה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּעוֹרְרֵנוּ לְצִיּוֹן בְשִׁכְלוּלָהּ, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּזַכֵּנוּ בְּנִבְנְתָה הָעִיר עַל תִּלָּהּ, הוֹשַׁע נָא.\nהוֹשַׁע נָא תַּרְבִּיצֵנוּ בְּשָׂשׂוֹן וְגִילָה, הוֹשַׁע נָא.\nהוֹשַׁע נָא תְּחַזְקֵנוּ אֱלֹהֵי יַעֲקֹב סֶלָה, הוֹשַׁע נָא.","cond":["hallel","sucot","hoshanaraba"]},{"kind":"instruction","text":"חזן וקהל:","cond":["hallel","sucot","hoshanaraba"]},{"kind":"text","text":"אָנָּא, הוֹשִׁיעָה נָּא.\n\nאָנָּא אֱזֹן חִין תְּאֵבֵי יִשְׁעָךְ, בְּעַרְבֵי נַחַל לְשַׁעְשְׁעָךְ, וְהוֹשִׁיעָה נָּא.\nאָנָּא גְאַל כַּנַּת נִטְעָךְ, דּוּמָה בְּטַאטְאָךְ, וְהוֹשִׁיעָה נָּא.\nאָנָּא הַבֵּט לַבְּרִית טִבְעָךְ, וּמַחֲשַׁכֵּי אֶרֶץ בְּהַטְבִּיעָךְ, וְהוֹשִׁיעָה נָּא.\nאָנָּא זְכָר לָנוּ אָב יִדְּעָךְ, חַסְדְּךָ לָמוֹ בְּהוֹדִיעָךְ, וְהוֹשִׁיעָה נָּא.\nאָנָּא טְהוֹרֵי לֵב בְּהַפְלִיאָךְ, יִוָּדַע כִּי הוּא פִלְאָךְ, וְהוֹשִׁיעָה נָּא.\nאָנָּא כַּבִּיר כֹּחַ תֵּן לָנוּ יִשְׁעָךְ, לַאֲבוֹתֵינוּ כְּהִשָּׁבְעָךְ, וְהוֹשִׁיעָה נָּא.\nאָנָּא מַלֵּא מִשְׁאֲלוֹת עַם מְשַׁוְּעָךְ, נֶעֱקַד בְּהַר מוֹר כְּמוֹ שִׁוְּעָךְ, וְהוֹשִׁיעָה נָּא.\nאָנָּא סַגֵּב אֶשְׁלֵי נִטְעָךְ, עָרִיצִים בַּהֲנִיעָךְ, וְהוֹשִׁיעָה נָּא.\nאָנָּא פְּתַח לָנוּ אוֹצְרוֹת רִבְעָךְ, צִיָּה מֵהֶם בְּהַרְבִּיעָךְ, וְהוֹשִׁיעָה נָּא.\nאָנָּא קוֹרְאֶיךָ אֶרֶץ בְּרוֹעֲעָךְ, רְעֵם בְּטוּב מִרְעָךְ, וְהוֹשִׁיעָה נָּא.\nאָנָּא שְׁעָרֶיךָ תַּעַל מִמְּשׁוֹאָךְ, תֵּל תַּלְפִּיּוֹת בְּהַשִּׁיאָךְ, וְהוֹשִׁיעָה נָּא.","cond":["hallel","sucot","hoshanaraba"]},{"kind":"instruction","text":"חזן וקהל:","cond":["hallel","sucot","hoshanaraba"]},{"kind":"text","text":"אָנָּא, אֵל נָא, הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא.\n\nאֵל נָּא תָּעִינוּ כְּשֶׂה אוֹבֵד, שְׁמֵנוּ מִסִּפְרְךָ אַל תְּאַבֵּד, הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא.\nאֵל נָּא רְעֵה אֶת צֹאן הַהֲרֵגָה, קְצוּפָה וְעָלֶיךָ הֲרוּגָה, הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא.\nאֵל נָא צֹאנְךָ וְצֹאן מַרְעִיתֶךָ, פְּעוּלָתֶךָ וְרַעְיָתֶךָ, הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא.\nאֵל נָא עֲנִיֵּי הַצֹּאן, שִׂיחָם עֲנֵה בְּעֵת רָצוֹן, הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא.\nאֵל נָא נוֹשְׂאֵי לְךָ עַיִן, מִתְקוֹמְמֶיךָ יִהְיוּ כְאַיִן, הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא.\nאֵל נָא לִמְנַסְּכֵי לְךָ מַיִם, כְּמִמַּעַיְנֵי הַיְּשׁוּעָה יִשְׁאֲבוּן מַיִם, הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא.\nאֵל נָא יַעֲלוּ לְצִיּוֹן מוֹשִׁיעִים, טְפוּלִים בְּךָ וּבְשִׁמְךָ נוֹשָׁעִים, הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא.\nאֵל נָא חֲמוּץ בְּגָדִים, זְעֹם לְנַעֵר כָּל בּוֹגְדִים, הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא.\nאֵל נָא וְזָכוֹר תִּזְכֹּר, הַנְּכוּרֵי בְּלֶתֶךְ וָכוֹר, הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא.\nאֵל נָא דּוֹרְשֶׁיךָ בְּעַנְפֵי עֲרָבוֹת, גַּעְיָם שְׁעֵה מֵעֲרָבוֹת, הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא.\nאֵל נָא בָּרֵךְ בְּעִטּוּר שָׁנָה, אֲמָרַי רְצֵה בְּפִלּוּלִי בְּיוֹם הוֹשַׁעְנָא, הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא.","cond":["hallel","sucot","hoshanaraba"]},{"kind":"instruction","text":"חזן וקהל:","cond":["hallel","sucot","hoshanaraba"]},{"kind":"text","text":"אָנָּא, אֵל נָא, הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא, אָבִינוּ אָתָּה.\n\nלְמַעַן תָּמִים בְּדוֹרוֹתָיו, הַנִּמְלָט בְּרֹב צִדְקוֹתָיו, מֻצָּל מִשֶּׁטֶף בְּבֹא מַבּוּל מַיִם, לְאוֹם אֲנִי חוֹמָה הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן שָׁלֵם בְּכָל מַעֲשִׂים, הַמְנֻּסָּה בַּעֲשָׂרָה נִסִּים, כְּשָׁר מַלְאָכִים נָם יֻקַּח נָא מְעַט מַיִם, לְבָרָה כַּחַמָּה הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן רַךְ וְיָחִיד נֶחֱנַט פְּרִי לְמֵאָה, זָעַק אַיֵּה הַשֶּׂה לְעוֹלָה, בִּשְׂרוּהוּ עֲבָדָיו מָצָאנוּ מַיִם, לְגוֹלָה וְסוּרָה הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן קִדַּם שְׂאֵת בְּרָכָה, הַנִּשְׂטַם וּלְשִׁמְךָ חִכָּה, מְיַחֵם בְּמַקְלוֹת בְּשִׁקְתוֹת הַמַּיִם, לְדָמְתָה לְתָמָר הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן צָדַק הֱיוֹת לְךָ לְכֹהֵן, כֶּחָתָן פְּאֵר יְכַהֵן, מְנֻסָּה בְּמַסָּה בְּמֵי מְרִיבַת מַיִם, לְהָהָר הַטּוֹב הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן פֹּאַר הֱיוֹת גְּבִיר לְאֶחָיו, יְהוּדָה אֲשֶׁר גָּבַר בְּאֶחָיו, מִסְפַּר רֹבַע מִדָּלְיָו יִזַּל מַיִם, לֹא לָנוּ כִּי אִם לְמַעַנְךָ הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן עָנָו מִכֹּל וְנֶאֱמָן, אֲשֶׁר בְּצִדְקוֹ כִּלְכֵּל הַמָּן, מָשׁוּךְ לְגוֹאֵל וּמָשׁוּי מִמַּיִם, לְזֹאת הַנִּשְׁקָפָה הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן שַׂמְתּוֹ כְּמַלְאֲכֵי מְרוֹמִים, הַלּוֹבֵשׁ אוּרִים וְתוּמִים, מְצֻוָּה לָבֹא בַּמִּקְדָּשׁ בְּקִדּוּשׁ יָדַיִם וְרַגְלַיִם וּרְחִיצַת מַיִם, לְחוֹלַת אַהֲבָה הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן נְבִיאָה מְחוֹלַת מַחֲנַיִם, לִכְמֵהֵי לֵב הוּשְׂמָה עֵינַיִם, לְרַגְלָהּ רָצָה עֲלוֹת וָרֶדֶת בְּאֵר מַיִם, לְטוֹבוּ אֹהָלָיו הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן מְשָׁרֵת לֹא מָשׁ מֵאֹהֶל, וְרוּחַ הַקֹּדֶשׁ עָלָיו אִהֵל, בְּעָבְרוֹ בַיַרְדֵּן נִכְרְתוּ הַמַּיִם, לְיָפָה וּבָרָה הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן לִמַּד רְאוֹת לְטוֹבָה אוֹת, זָעַק אַיֵה נִפְלָאוֹת, מִצָּה טַל מִגִּזָּה מְלֹא הַסֵּפֶל מַיִם, לְכַלַּת לְבָנוֹן הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן כְּלוּלֵי עֲשׂוֹת מִלְחַמְתֶּךָ, אֲשֶׁר בְּיָדָם תַּתָּה יְשׁוּעָתֶךָ, צְרוּפֵי מִגּוֹי בְּלָקְקָם בְּיָדָם מַיִם, לְלֹא בָּגְדוּ בָךְ הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן יָחִיד צוֹרְרִים דָּשׁ, אֲשֶׁר מֵרֶחֶם לְנָזִיר הֻקְדָּשׁ, מִמַּכְתֵּשׁ לֶחִי הִבְקַעְתָּ לוֹ מַיִם, לְמַעַן שֵׁם קָדְשְׁךָ הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן טוֹב הוֹלֵךְ וְגָדֵל, אֲשֶׁר מֵעֹשֶׁק עֵדָה חִדֵּל, בְּשׁוּב עָם מֵחֵטְא צָו שְׁאָב מַיִם, לְנָאוָה כִּירוּשָׁלָיִם הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן חֵיךְ מְכַרְכֵּר בְּשִׁיר, הַמְלַמֵּד תּוֹרָה בְּכָל כְּלֵי שִׁיר, מְנַסֵּךְ לְפָנָיו כְּתָאַב שְׁתוֹת מַיִם, לְשָׂמוּ בְךָ סִבְרָם הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן זָךְ עָלָה בִּסְעָרָה, הַמְקַנֵּא וּמֵשִׁיב עֶבְרָה, לְפִלּוּלוֹ יָרְדָה אֵשׁ וְלִחֲכָה עָפָר וּמַיִם, לְעֵינֶיהָ בְּרֵכוֹת הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן וְשֵׁרֵת בֶּאֱמֶת לְרַבּוֹ, פִּי שְׁנַיִם בְּרוּחוֹ נֶאֱצַל בּוֹ, בְּקַחְתּוֹ מְנַגֵּן נִתְמַלְּאוּ גֵבִים מַיִם, לְפוֹצְחֵי מִי כָמוֹךָ הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן הִרְהֵר עֲשׂוֹת רְצוֹנֶךָ, הַמַּכְרִיז תְּשׁוּבָה לְצֹאנֶךָ, אָז בְּבֹא מְחָרֵף סָתַם עֵינוֹת מַיִם, לְצִיּוֹן מִכְלַל יוֹפִי הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן דְּרָשׁוּךָ בְּתוֹךְ הַגּוֹלָה, וְסוֹדְךָ לָמוֹ נִגְלָה, בְּלִי לְהִתְגָּאֵל דָּרְשׁוּ זֵרְעוֹנִים וּמַיִם, לְקוֹרְאֶיךָ בַּצָּר הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן גָּמַר חָכְמָה וּבִינָה, סוֹפֵר מָהִיר מְפַלֵּשׁ אֲמָנָה, מְחַכְּמֵנוּ אֲמָרִים הַמְשׁוּלִים בְּרַחֲבֵי מַיִם, לְרַבָּתִי עָם הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן בָּאֵי לְךָ הַיּוֹם בְּכָל לֵב, שׁוֹפְכִים לְךָ שִׂיחַ בְּלֹא לֵב וָלֵב, שׁוֹאֲלִים מִמְּךָ עֹז מִטְרוֹת מַיִם, לְשׁוֹרְרוּךָ בַּיָם הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.\nלְמַעַן אוֹמְרֵי יִגְדַּל שְׁמֶךָ, וְהֵם נַחֲלָתְךָ וְעַמֶּךָ, צְמֵאִים לְיֶשְׁעֲךָ כְּאֶרֶץ עֲיֵפָה לְמַיִם, לְתַרְתָּ לָמוֹ מְנוּחָה הוֹשַׁע נָא וְהוֹשִׁיעָה נָּא אָבִינוּ אָתָּה.","cond":["hallel","sucot","hoshanaraba"]},{"kind":"instruction","text":"חזן וקהל:","cond":["hallel","sucot","hoshanaraba"]},{"kind":"text","text":"הוֹשַׁע נָא, אֵל נָא, אָנָּא הוֹשִׁיעָה נָּא.\nהוֹשַׁע נָא, סְלַח נָּא, וְהַצְלִיחָה נָא, וְהוֹשִׁיעֵנוּ אֵל מָעֻזֵנוּ.","cond":["hallel","sucot","hoshanaraba"]},{"kind":"instruction","text":"מניח הלולב מידו ולוקח את ערבות ההושענא ותופסן עד החבטה.","cond":["hallel","sucot","hoshanaraba"]},{"kind":"text","text":"תַּעֲנֶה אֱמוּנִים שׁוֹפְכִים לְךָ לֵב כַּמַּיִם, וְהוֹשִׁיעָה נָּא.\nלְמַעַן בָּא בָאֵשׁ וּבַמַּיִם, וְהַצְלִיחָה נָּא\nגָּזַר וְנָם יֻקַּח נָא מְעַט מַיִם, וְהוֹשִׁיעֵנוּ אֵל מָעֻזֵּנוּ.\n\nתַּעֲנֶה דְגָלִים גָּזוּ גִזְרֵי מַיִם, וְהוֹשִׁיעָה נָּא.\nלְמַעַן הַנֶּעֱקַד בְּשַׁעַר הַשָּׁמַיִם, וְהַצְלִיחָה נָּא\nוְשָׁב וְחָפַר בְּאֵרוֹת מַיִם, וְהוֹשִׁיעֵנוּ אֵל מָעֻזֵּנוּ.\n\nתַּעֲנֶה זַכִּים חוֹנִים עֲלֵי מַיִם, וְהוֹשִׁיעָה נָּא.\nלְמַעַן חָלָק מְפַצֵּל מַקְלוֹת בְּשִׁקְתוֹת הַמַּיִם, וְהַצְלִיחָה נָּא.\nטָעַן וְגָל אֶבֶן מִבְּאֵר מַיִם, וְהוֹשִׁיעֵנוּ אֵל מָעֻזֵּנוּ.\n\nתַּעֲנֶה יְדִידִים נוֹחֲלֵי דָת מְשׁוּלַת מַיִם, וְהוֹשִׁיעָה נָּא.\nלְמַעַן כָּרוּ בְּמִשְׁעֲנוֹתָם מַיִם, וְהַצְלִיחָה נָּא.\nלְהָכִין לָמוֹ וּלְצֶאֱצָאֵימוֹ מַיִם, וְהוֹשִׁיעֵנוּ אֵל מָעֻזֵּנוּ.\n\nתַּעֲנֶה מִתְחַנְּנִים כְּבִישִׁימוֹן עֲלֵי מַיִם, וְהוֹשִׁיעָה נָּא.\nלְמַעַן נֶאֱמַן בַּיִת מַסְפִּיק לָעָם מַיִם, וְהַצְלִיחָה נָּא.\nסֶלַע הָךְ וַיָּזוּבוּ מַיִם, וְהוֹשִׁיעֵנוּ אֵל מָעֻזֵּנוּ.\n\nתַּעֲנֶה עוֹנִים עֲלִי בְאֵר מַיִם, וְהוֹשִׁיעָה נָּא.\nלְמַעַן פֻּקַּד בְּמֵי מְרִיבַת מַיִם, וְהַצְלִיחָה נָּא.\nצְמֵאִים לְהַשְׁקוֹתָם מַיִם, וְהוֹשִׁיעֵנוּ אֵל מָעֻזֵּנוּ.\n\nתַּעֲנֶה קְדוֹשִׁים מְנַסְּכִים לְךָ מַיִם, וְהוֹשִׁיעָה נָּא.\nלְמַעַן רֹאשׁ מְשׁוֹרְרִים כְּתָאַב שְׁתוֹת מַיִם, וְהַצְלִיחָה נָּא.\nחָלִילָה פָּץ וְנָסַךְ לְךָ מַיִם, וְהוֹשִׁיעֵנוּ אֵל מָעֻזֵּנוּ.\n\nתַּעֲנֶה שׁוֹאֲלִים בְּרִבּוּעַ אֶשְׁלֵי מַיִם, וְהוֹשִׁיעָה נָּא.\nלְמַעַן תֵּל תַּלְפִּיּוֹת מוֹצָא מַיִם, וְהַצְלִיחָה נָּא.\nתִּפְתַּח אֶרֶץ וְתַרְעִיף שָׁמַיִם, וְהוֹשִׁיעֵנוּ אֵל מָעֻזֵּנוּ.","cond":["hallel","sucot","hoshanaraba"]},{"kind":"instruction","text":"חזן וקהל:","cond":["hallel","sucot","hoshanaraba"]},{"kind":"text","text":"רַחֶם נָא קְהַל עֲדַת יְשֻׁרוּן, סְלַח וּמְחַל עֲוׂנָם, וְהוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ.\n\nאָז כְּעֵינֵי עֲבָדִים אֶל יַד אֲדוֹנִים, בָּאנוּ לְפָנֶיךָ נִדּוֹנִים, וְהוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ.\nגֵּאֶה אֲדוֹנֵי הָאֲדוֹנִים, נִתְגָּרוּ בָנוּ מְדָנִים, דָּשׁוּנוּ וּבְעָלוּנוּ זוּלָתְךָ אֲדוֹנִים, וְהוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ.\nהֵן גַּשְׁנוּ הַיּוֹם בְּתַחֲנוּן, עָדֶיךָ רַחוּם וְחַנוּן, וְסִפַּרְנוּ נִפְלְאוֹתֶיךָ בְּשִׁנּוּן, וְהוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ.\nזָבַת חָלָב וּדְבָשׁ, נָא אַל תִּיבָשׁ, חַשְׁרַת מַיִם כְּאֵבָיהָ תֶּחְבָּשׁ, וְהוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ.\nטְעֵנוּ בִשְׁמֵנָה, בְּיַד שִׁבְעָה וּשְׁמוֹנָה, יָשָׁר צַדִּיק אֵל אֱמוּנָה, וְהוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ.\nכָּרַתָּ בְרִית לָאָרֶץ, עוֹד כָּל יְמֵי הָאָרֶץ, לְבִלְתִּי פְרָץ בָּהּ פָּרֶץ, וְהוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ.\nמִתְחַנְּנִים עֲלֵי מַיִם, כַּעֲרָבִים עַל יִבְלֵי מַיִם, נָא זְכוֹר לָנוּ נִסּוּךְ הַמַּיִם, וְהוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ.\nשִׂיחִים בְּדֶרֶךְ מַטָּעָתָם, עוֹמְסִים בְּשַׁוְעָתָם, עֲנֵם בְּקוֹל פְּגִיעָתָם, וְהוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ.\nפּוֹעֵל יְשׁוּעוֹת, פְּנֵה לְפִלּוּלָם שְׁעוֹת, צַדְּקֵם אֵל לְמוֹשָׁעוֹת, וְהוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ.\nקוֹל רִגְשָׁם תִּשַׁע, תִּפְתַּח אֶרֶץ וְיִפְרוּ יֶשַׁע, רַב לְהוֹשִׁיעַ וְלֹא חָפֵץ רֶשַׁע, וְהוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ.","cond":["hallel","sucot","hoshanaraba"]},{"kind":"instruction","text":"חזן וקהל:","cond":["hallel","sucot","hoshanaraba"]},{"kind":"text","text":"שַׁעֲרֵי שָׁמַיִם פְּתַח, וְאוֹצָרְךָ הַטּוֹב לָנוּ תִפְתַּח, תּוֹשִׁיעֵנוּ וְרִיב אַל תִּמְתַּח, וְהוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ.","cond":["hallel","sucot","hoshanaraba"]},{"kind":"instruction","text":"חזן וקהל:","cond":["hallel","sucot","hoshanaraba"]},{"kind":"text","text":"קוֹל מְבַשֵּׂר מְבַשֵּׂר וְאוֹמֵר.\n\nאֹמֶץ יֶשְׁעֲךָ בָּא, קוֹל דּוֹדִי הִנֵּה זֶה בָּא, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל בָּא בְּרִבְבוֹת כִּתִּים, לַעֲמֹד עַל הַר הַזֵּיתִים, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל גִּשְׁתּוֹ בַּשּׁוֹפָר לִתְקַע, תַּחְתָּיו הַר יִבָּקַע, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל דָּפַק וְהֵצִיץ וְזָרַח, וּמָשׁ חֲצִי הָהָר מִמִּזְרָח, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל הֵקִים מִלּוּל נוֹאֲמוֹ, וּבָא הוּא וְכָל קְדוֹשָׁיו עִמּוֹ, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל וּלְכָל בָּאֵי עוֹלָם, בַּת קוֹל יִשָּׁמַע בָּעוֹלָם, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל זֶרַע עֲמוּסֵי רְחָמוֹ, נוֹלְדוּ כְּיֶלֶד מִמְּעֵי אִמּוֹ, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל חָלָה וְיָלְדָה מִי זֹאת, מִי שָׁמַע כָּזֹאת, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל טָהוֹר פָּעַל כָּל אֵלֶּה, וּמִי רָאָה כָּאֵלֶּה, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל יֶשַׁע וּזְמָן הוּחָד, הֲיוּחַל אֶרֶץ בְּיוֹם אֶחָד, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל כַּבִּיר רוּם וָתַחַת, אִם יִוָּלֶד גּוֹי פַּעַם אֶחָת, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל לְעֵת יִגְאַל עַמּוֹ נָאוֹר, וְהָיָה לְעֵת עֶרֶב יִהְיֶה אוֹר, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל מוֹשִׁיעִים יַעֲלוּ לְהַר צִיּוֹן, כִּי חָלָה גַּם יָלְדָה צִיּוֹן, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל נִשְׁמַע בְּכָל גְּבוּלֵךְ, הַרְחִיבִי מְקוֹם אָהֳלֵךְ, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל שִׂימִי עַד דַּמֶּשֶׂק מִשְׁכְּנוֹתַיִךְ, קַבְּלִי בָנַיִךְ וּבְנוֹתַיִךְ, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל עִלְזִי חֲבַצֶּלֶת הַשָּׁרוֹן, כִּי קָמוּ יְשֵׁנֵי חֶבְרוֹן, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל פְּנוּ אֵלַי וְהִוָּשְׁעוּ, הַיּוֹם אִם בְּקוֹלִי תִשְׁמָעוּ, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל צָמַח אִישׁ צֶמַח שְׁמוֹ, הוּא דָּוִד בְּעַצְמוֹ, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל קוּמוּ כְּפוּשֵׁי עָפָר, הָקִיצוּ וְרַנְּנוּ שׁוֹכְנֵי עָפָר, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל רַבָּתִי עָם בְּהַמְלִיכוֹ, מִגְדּוֹל יְשׁוּעוֹת מַלְכּוֹ, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל שֵׁם רְשָׁעִים לְהַאֲבִיד, עֹשֶׂה חֶסֶד לִמְשִׁיחוֹ לְדָוִד, מְבַשֵּׂר וְאוֹמֵר.\nקוֹל תְּנָה יְשׁוּעוֹת לְעַם עוֹלָם, לְדָוִד וּלְזַרְעוֹ עַד עוֹלָם, מְבַשֵּׂר וְאוֹמֵר.","cond":["hallel","sucot","hoshanaraba"]},{"kind":"instruction","text":"חזן וקהל:","cond":["hallel","sucot","hoshanaraba"]},{"kind":"text","text":"קוֹל מְבַשֵּׂר מְבַשֵּׂר וְאוֹמֵר.\nקוֹל מְבַשֵּׂר מְבַשֵּׂר וְאוֹמֵר.\nקוֹל מְבַשֵּׂר מְבַשֵּׂר וְאוֹמֵר.","cond":["hallel","sucot","hoshanaraba"]},{"kind":"instruction","text":"חובטים את הערבות חמש פעמים ואומרים:","cond":["hallel","sucot","hoshanaraba"]},{"kind":"text","text":"הוֹשִׁיעָה אֶת עַמֶּךָ, וּבָרֵךְ אֶת נַחֲלָתֶךָ, וּרְעֵם וְנַשְּׂאֵם עַד הָעוֹלָם: וְיִהְיוּ דְּבָרַי אֵלֶּה אֲשֶׁר הִתְחַנַּנְתִּי לִפְנֵי יהוה, קְרוֹבִים אֶל יהוה אֱלֹהֵינוּ יוֹמָם וָלָיְלָה, לַעֲשׂוֹת מִשְׁפַּט עַבְדּוֹ וּמִשְׁפַּט עַמּוֹ יִשְׂרָאֵל דְּבַר יוֹם בְּיוֹמוֹ: לְמַעַן דַּעַת כָּל עַמֵּי הָאָרֶץ, כִּי יהוה הוּא הָאֱלֹהִים אֵין עוֹד:","cond":["hallel","sucot"]},{"kind":"instruction","text":"מחזירים את ספר התורה לארון הקודש.","cond":["hallel","sucot","noHoshanaraba"]},{"kind":"instruction","text":"מחזירים את ספרי התורה ואומרים תחינה זו. יש אומרים את התחינה לאחר הקדיש.","cond":["hallel","sucot","hoshanaraba"]},{"kind":"text","text":"יְהִי רָצוֹן מִלְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, הַבּוֹחֵר בִּנְבִיאִים טוֹבִים וּבְמִנְהָגֵיהֶם הַטּוֹבִים, שֶׁתְּקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ וַהֲקָפוֹתֵינוּ, וּזְכָר לָנוּ זְכוּת שִׁבְעַת תְּמִימֶיךָ, וְתָסִיר מְחִיצַת הַבַּרְזֶל הַמַּפְסֶקֶת בֵּינֵינוּ וּבֵינֶיךָ, וְתַאֲזִין שַׁוְעָתֵנוּ, וְתֵיטִיב לָנוּ הַחֲתִימָה, תּוֹלֶה אֶרֶץ עַל בְּלִימָה, וְחָתְמֵנוּ בְּסֵפֶר חַיִּים טוֹבִים. וְהַיּוֹם הַזֶּה תִּתֵּן בִּשְׁכִינַת עֻזֶּךָ חָמֵשׁ גְּבוּרוֹת מְמֻתָּקוֹת, עַל יְדֵי חֲבִיטַת עֲרָבָה מִנְהַג נְבִיאֶיךָ הַקְּדוֹשִׁים, וְתִתְעוֹרֵר הָאַהֲבָה בֵּינֵיהֶם, וּתְנַשְּׁקֵנוּ מִנְּשִׁיקוֹת פִּיךָ, מַמְתֶּקֶת כָּל הַגְּבוּרוֹת וְכָל הַדִּינִין, וְתָאִיר לִשְׁכִינַת עֻזֶּךָ בְּשֵׁם (יו\"ד ה\"א וא\"ו) שֶׁהוּא טַל אוֹרוֹת טַלֶּךָ, וּמִשָּׁם תַּשְׁפִּיעַ שֶׁפַע לְעַבְדְּךָ הַמִּתְפַּלֵּל לְפָנֶיךָ, שֶׁתַּאֲרִיךְ יָמָיו וְתִמְחַל לוֹ חֲטָאָיו וַעֲוׂנוֹתָיו וּפְשָׁעָיו, וְתִפְשֹׁט יְמִינְךָ וְיָדְךָ לְקַבְּלוֹ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ. וְאוֹצָרְךָ הַטּוֹב תִּפְתַּח לְהַשְׂבִּיעַ מַיִם נֶפֶשׁ שׁוֹקֵקָה, כְּמוֹ שֶׁכָּתוּב: יִפְתַּח יהוה לְךָ אֶת אוֹצָרוֹ הַטּוֹב אֶת הַשָּׁמַיִם, לָתֵת מְטַר אַרְצְךָ בְּעִתּוֹ, וּלְבָרֵךְ אֶת כָּל מַעֲשֵׂה יָדֶךָ. אָמֵן.","cond":["hallel","sucot","hoshanaraba"]},{"kind":"instruction","text":"קדיש תתקבל","cond":["hallel","musaf"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":["hallel","musaf"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["hallel","musaf","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["hallel","musaf","ayt"]},{"kind":"text","text":"תִּתְקַבַּל צְלוֹתְהוֹן וּבָעוּתְהוֹן דְּכָל בֵּית יִשְׂרָאֵל קֳדָם אֲבוּהוֹן דִּי בִשְׁמַיָּא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":["hallel","musaf"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["hallel","musaf","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["hallel","musaf","ayt"]},{"kind":"header","text":"אבינו מלכנו","cond":["avinu_malkenu_kipur"]},{"kind":"instruction","text":"אבינו מלכנו","cond":["avinu_malkenu_kipur"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חָטָאנוּ לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, אֵין לָנוּ מֶלֶךְ אֶלָּא אָתָּה.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה עִמָּנוּ לְמַעַן שְׁמֶךָ.","cond":["avinu_malkenu_kipur"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חַדֵּשׁ עָלֵינוּ שָׁנָה טוֹבָה.","cond":["avinu_malkenu_kipur","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, בָּרֵךְ עָלֵינוּ שָׁנָה טוֹבָה.","cond":["avinu_malkenu_kipur","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, בַּטֵּל מֵעָלֵינוּ כָּל גְּזֵרוֹת קָשׁוֹת.\nאָבִינוּ מַלְכֵּנוּ, בַּטֵּל מַחְשְׁבוֹת שׂוֹנְאֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, הָפֵר עֲצַת אוֹיְבֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה כָּל צַר וּמַשְׂטִין מֵעָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, סְתֹם פִּיּוֹת מַשְׂטִינֵינוּ וּמְקַטְרְגֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה דֶבֶר וְחֶרֶב וְרָעָב וּשְׁבִי וּמַשְׁחִית וְעָוׂן וּשְׁמַד מִבְּנֵי בְרִיתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, מְנַע מַגֵּפָה מִנַּחֲלָתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, סְלַח וּמְחַל לְכָל עֲוׂנוֹתֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, מְחֵה וְהַעֲבֵר פְּשָׁעֵינוּ וְחַטֹּאתֵינוּ מִנֶּגֶד עֵינֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, מְחֹק בְּרַחֲמֶיךָ הָרַבִּים כָּל שִׁטְרֵי חוֹבוֹתֵינוּ.","cond":["avinu_malkenu_kipur"]},{"kind":"instruction","text":"מכאן אומרים בקול עם החזן","cond":["avinu_malkenu_kipur"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, הַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, שְׁלַח רְפוּאָה שְׁלֵמָה לְחוֹלֵי עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, קְרַע רֹע גְּזַר דִּינֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ בְּזִכְרוֹן טוֹב לְפָנֶיךָ.","cond":["avinu_malkenu_kipur"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר חַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר גְּאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר פַּרְנָסָה וְכַלְכָּלָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר זְכֻיּוֹת.\nאָבִינוּ מַלְכֵּנוּ, כָָּתְבֵנוּ בְּסֵפֶר סְלִיחָה וּמְחִילָה.","cond":["avinu_malkenu_kipur","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לְחַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִגְאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לְפַרְנָסָה וְכַלְכָּלָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִזְכֻיּוֹת.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִסְלִיחָה וּמְחִילָה.","cond":["avinu_malkenu_kipur","noGedalya"]},{"kind":"instruction","text":"עד כאן עם החזן","cond":["avinu_malkenu_kipur"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, הַצְמַח לָנוּ יְשׁוּעָה בְּקָרוֹב.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן יִשְׂרָאֵל עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן מְשִׁיחֶךָ.\nאָבִינוּ מַלְכֵּנוּ, מַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, מַלֵּא אֲסָמֵינוּ שָׂבָע.\nאָבִינוּ מַלְכֵּנוּ, שְׁמַע קוֹלֵנוּ, חוּס וְרַחֵם עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, קַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, פְּתַח שַׁעֲרֵי שָׁמַיִם לִתְפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, זְכֹר כִּי עָפָר אֲנַחְנוּ.\nאָבִינוּ מַלְכֵּנוּ, נָא אַל תְּשִׁיבֵנוּ רֵיקָם מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, תְּהֵא הַשָּׁעָה הַזֹּאת שְׁעַת רַחֲמִים וְעֵת רָצוֹן מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, חֲמֹל עָלֵינוּ וְעַל עוֹלָלֵינוּ וְטַפֵּנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן הֲרוּגִים עַל שֶׁם קָדְשֶׁךָ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן טְבוּחִים עַל יִחוּדֶךָ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן בָּאֵי בָאֵשׁ וּבַמָּיִּם עַל קִדּוּשׁ שְׁמֶךָ.\nאָבִינוּ מַלְכֵּנוּ, נְקֹם נִקְמַת דַּם עֲבָדֶיךָ הַשָּׁפוּךְ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַנְךָ אִם לֹא לְמַעַנֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַנְךָ וְהוֹשִׁיעֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַן רַחֲמֶיךָ הָרַבִּים.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַן שִׁמְךָ הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא שֶׁנִּקְרָא עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, חָנֵּנוּ וַעֲנֵנוּ כִּי אֵין בָּנוּ מַעֲשִׂים, עֲשֵׂה עִמָּנוּ צְדָקָה וָחֶסֶד וְהוֹשִׁיעֵנוּ.","cond":["avinu_malkenu_kipur"]},{"kind":"header","text":"תחנון","cond":["shacharitTachanun"]},{"kind":"instruction","text":"יש נוהגים שלא לומר תחנון היום, ובפרט בארץ ישראל שיכולים בקלות להגיע לירושלים לשמוח עימם בשמחת פורים דמוקפין.","cond":["shacharitTachanun","purim_meshulash_tachanun_message"]},{"kind":"instruction","text":"בבית האבל אין אומרים תחנון ומדלגים לחצי קדיש.","cond":["shacharitTachanun"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, תָּבוֹא לְפָנֶיךָ תְּפִלָּתֵנוּ וְאַל תִּתְעַלַּם מִתְּחִנָּתֵנוּ, שֶׁאֵין אָנוּ עַזֵּי פָנִים וּקְשֵׁי עֹרֶף לוֹמַר לְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ צַדִּיקִים אֲנַחְנוּ וְלֹא חָטָאנוּ, אֲבָל אֲנַחְנוּ וַאֲבוֹתֵינוּ חָטָאנוּ.\nאָשַׁמְנוּ, בָּגַדְנוּ, גָּזַלְנוּ, דִּבַּרְנוּ דֹפִי. הֶעֱוִינוּ, וְהִרְשַׁעְנוּ, זַדְנוּ, חָמַסְנוּ, טָפַלְנוּ שֶׁקֶר. יָעַצְנוּ רָע, כִּזַּבְנוּ, לַצְנוּ, מָרַדְנוּ, נִאַצְנוּ, סָרַרְנוּ, עָוִינוּ, פָּשַׁעְנוּ, צָרַרְנוּ, קִשִּׁינוּ עֹרֶף. רָשַׁעְנוּ, שִׁחַתְנוּ, תִּעַבְנוּ, תָּעִינוּ, תִּעְתַּעְנוּ.\nסַרְנוּ מִמִּצְוׂתֶיךָ וּמִמִּשְׁפָּטֶיךָ הַטּוֹבִים וְלֹא שָׁוָה-לָנוּ. וְאַתָּה צַדִּיק עַל כָּל הַבָּא עָלֵינוּ, כִּי אֱמֶת עָשִׂיתָ, וַאֲנַחְנוּ הִרְשָׁעְנוּ:","cond":["shacharitTachanun"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun"]},{"kind":"text","text":"אֵל אֶרֶךְ אַפַּיִם אַתָּה וּבַעַל הָרַחֲמִים נִקְרֵאתָ, וְדֶרֶךְ תְּשׁוּבָה הוֹרֵיתָ, גְּדֻלַּת רַחֲמֶיךָ וַחֲסָדֶיךָ תִּזְכֹּר הַיּוֹם וּבְכָל יוֹם לְזֶרַע יְדִידֶיךָ. תֵּפֶן אֵלֵינוּ בְּרַחֲמִים, כִּי אַתָּה הוּא בַּעַל הָרַחֲמִים. בְּתַחֲנוּן וּבִתְפִלָּה פָּנֶיךָ נְקַדֵּם, כְּהוֹדַעתָּ לֶעָנָו מִקֶּדֶם. מֵחֲרוֹן אַפְּךָ שׁוּב, כְּמוֹ בְּתוֹרָתְךָ כָּתוּב. וּבְצֵל כְּנָפֶיךָ נֶחְסֶה וְנִתְלוֹנָן, כְּיוֹם וַיֵּרֶד יהוה בֶּעָנָן. תַּעֲבֹר עַל פֶּשַׁע וְתִמְחֶה אָשָׁם, כְּיוֹם וַיִּתְיַצֵּב עִמּוֹ שָׁם. תַּאֲזִין שַׁוְעָתֵנוּ וְתַקְשִׁיב מֶנּוּ מַאֲמָר, כְּיוֹם וַיִּקְרָא בְשֵׁם יהוה, וְשָׁם נֶאֲמַר:\n\nוַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לַאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun"]},{"kind":"instruction","text":"נפילת אפיים","cond":["shacharitTachanun"]},{"kind":"text","text":"וַיֹּאמֶר דָּוִד אֶל גָּד, צַר לִי מְאֹד, נִפְּלָה נָּא בְיַד יהוה כִּי רַבִּים רַחֲמָיו, וּבְיַד אָדָם אַל אֶפֹּלָה:\n\nרַחוּם וְחַנּוּן חָטָאתִי לְפָנֶיך. יהוה מָלֵא רַחֲמִים, רַחֵם עָלַי וְקַבֵּל תַּחֲנוּנָי.\n\nיהוה, אַל בְּאַפְּךָ תוֹכִיחֵנִי וְאַל בַּחֲמָתְךָ תְיַסְּרֵנִי: חָנֵּנִי יהוה כִּי אֻמְלַל אָנִי, רְפָאֵנִי יהוה כִּי נִבְהֲלוּ עֲצָמָי: וְנַפְשִׁי נִבְהֲלָה מְאֹד, וְאַתָּה יהוה עַד מָתָי: שׁוּבָה יהוה חַלְּצָה נַפְשִׁי, הוֹשִׁיעֵנִי לְמַעַן חַסְדֶּךָ: כִּי אֵין בַּמָּוֶת זִכְרֶךָ, בִּשְׁאוֹל מִי יוֹדֶה לָּךְ: יָגַעְתִּי בְאַנְחָתִי, אַשְׂחֶה בְכָל לַיְלָה מִטָּתִי, בְּדִמְעָתִי עַרְשִׂי אַמְסֶה: עָשְׁשָׁה מִכַּעַס עֵינִי, עָתְקָה בְּכָל צוֹרְרָי: סוּרוּ מִמֶּנִּי כָּל פֹּעֲלֵי אָוֶן כִּי שָׁמַע יהוה קוֹל בִּכְיִי: שָׁמַע יהוה תְּחִנָּתִי, יהוה תְּפִלָּתִי יִקָּח: יֵבֹשׁוּ וְיִבָּהֲלוּ מְאֹד כָּל אֹיְבָי, יָשֻׁבוּ יֵבֹשׁוּ רָגַע:","cond":["shacharitTachanun"]},{"kind":"header","text":"סליחות לשבעה עשר בתמוז","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"סליחות לשבעה עשר בתמוז","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"סְלַח לָנוּ אָבִינוּ כִּי בְּרֹב אִוַּלְתֵּנוּ שָׁגִינוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי רַבּוּ עֲוׂנֵינוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אֵל אֶרֶךְ אַפַּיִם אַתָּה וּבַעַל הָרַחֲמִים נִקְרֵאתָ, וְדֶרֶךְ תְּשׁוּבָה הוֹרֵיתָ, גְּדֻלַּת רַחֲמֶיךָ וַחֲסָדֶיךָ תִּזְכֹּר הַיּוֹם וּבְכָל יוֹם לְזֶרַע יְדִידֶיךָ. תֵּפֶן אֵלֵינוּ בְּרַחֲמִים, כִּי אַתָּה הוּא בַּעַל הָרַחֲמִים. בְּתַחֲנוּן וּבִתְפִלָּה פָּנֶיךָ נְקַדֵּם, כְּהוֹדַעתָּ לֶעָנָו מִקֶּדֶם. מֵחֲרוֹן אַפְּךָ שׁוּב, כְּמוֹ בְּתוֹרָתְךָ כָּתוּב. וּבְצֵל כְּנָפֶיךָ נֶחְסֶה וְנִתְלוֹנָן, כְּיוֹם וַיֵּרֶד יהוה בֶּעָנָן. תַּעֲבֹר עַל פֶּשַׁע וְתִמְחֶה אָשָׁם, כְּיוֹם וַיִּתְיַצֵּב עִמּוֹ שָׁם. תַּאֲזִין שַׁוְעָתֵנוּ וְתַקְשִׁיב מֶנּוּ מַאֲמָר, כְּיוֹם וַיִּקְרָא בְשֵׁם יהוה, וְשָׁם נֶאֲמַר:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אַל תִּתְּנוּ דֳמִי לוֹ, עַד יְכוֹנֵן וְעַד יָשִׂים אֶת יְרוּשָׁלַיִם תְּהִלָּה בָּאָרֶץ: כִּי עִמְּךָ מְקוֹר חַיִּים, בְּאוֹרְךָ נִרְאֶה אוֹר: אֱלֹהֵינוּ, בּוֹשְׁנוּ בְּמַעֲשֵׂינוּ וְנִכְלַמְנוּ בַּעֲוׂנֵינוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"כְּרַחֵם אָב עַל בָּנִים, כֵּן תְּרַחֵם יהוה עָלֵינוּ. לַיהוה הַיְּשׁוּעָה, עַל עַמְּךָ בִרְכָתֶךָ סֶּלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶּלָה: יהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"סְלַח נָא לַעֲוׂן הָעָם הַזֶּה כְּגֹדֶל חַסְדֶּךָ, וְכַאֲשֶׁר נָשָׂאתָה לָעָם הַזֶּה מִמִּצְרַיִם וְעַד הֵנָּה: וְשָׁם נֶאֱמַר:","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"קהל ואחריו שליח הציבור:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"וַיֹּאמֶר יהוה: סָלַחְתִּי כִּדְבָרֶךָ:\n\nהַטֵּה אֱלֹהַי אָזְנְךָ וּשֲׁמָע, פְּקַח עֵינֶיךָ וּרְאֵה שׁוֹמְמוֹתֵינוּ וְהָעִיר אֲשֶׁר נִקְרָא שִׁמְךָ עָלֶיהָ, כִּי לֹא עַל צִדְקוֹתֵינוּ אֲנַחְנוּ מַפִּילִים תַּחֲנוּנֵינוּ לְפָנֶיךָ, כִּי עַל רַחֲמֶיךָ הָרַבִּים: אֲדֹנָי שְׁמָעָה, אֲדֹנָי סְלָחָה, אֲדֹנָי הַקְשִׁיבָה וַעֲשֵׂה אַל תְּאַחַר, לְמַעַנְךָ אֱלֹהַי, כִּי שִׁמְךָ נִקְרָא עַל עִירְךָ וְעַל עַמֶּךָ:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אָתָאנוּ לְךָ יוֹצֵר רוּחוֹת, בְּרוֹב עֲוׂנֵינוּ כָּבְדוּ אֲנָחוֹת, גְּזֵרוֹת עָצְמוּ וְרַבּוּ צְרִיחוֹת, כִּי בְּשִׁבְעָה עָשָׂר בְּתַמּוּז נִשְׁתַּבְּרוּ הַלּוּחוֹת. גָּלִינוּ מִבֵּית הַבְּחִירָה, דִּינֵנוּ נֶחְתַּם וְנִגְזְרָה גְזֵרָה, וְחָשַׁךְ בַּעֲדֵנוּ אוֹרָה, כִּי בְּשִׁבְעָה עָשָׂר בְּתַמּוּז נִשְׂרְפָה הַתּוֹרָה. הָרְסוּ אוֹיְבֵינוּ הַהֵיכָל, וּבָרְחָה שְׁכִינָה מִזָּוִית הֵיכָל, וְנִמְסַרְנוּ בִּידֵי זֵדִים לְהִתְאַכָּל, כִּי בְּשִׁבְעָה עָשָׂר בְּתַמּוּז הָעֳמַד צֶלֶם בְּהֵיכָל. זֵרוּנוּ מֵעִיר אֶל עִיר, וְנִלְכַּד מֶנּוּ רַב וְצָעִיר, חָרְבָה מְשׂוֹשֵׂנו וְאֵשׁ בָּהּ הִבְעִיר, כִּי בְּשִׁבְעָה עָשָׂר בְּתַמּוּז הָבְקְעָה הָעִיר. טָפַשׁ מִקְדָּשֵׁנוּ צַר הַמַּשְׁמִיד, וְנֻטַּל מֵחָתָן וְכַלָּה אֶצְעָדָה וְצָמִיד, יַעַן כִּעַסְנוּךָ נִתַּנּוּ לְהַשְׁמִיד, כִּי בְּשִׁבְעָה עָשָׂר בְּתַמּוּז בֻּטַּל הַתָּמִיד. כָּלָה מֶנּוּ כָּל הוֹד וָשֶׁבַח, חַרְבּוֹ שָׁלַף אוֹיֵב עָלֵינוּ לָאֶבַח, לִהְיוֹת עוֹלְלִים וְיוֹנְקִים מוּכָנִים לַטֶּבַח, כִּי בְּשִׁבְעָה עָשָׂר בְּתַמּוּז בָּטְלוּ עוֹלָה וָזָבַח. מָרַדְנוּ לְשׁוֹכֵן מְעוֹנוֹת, לָכֵן נִתְפַּזַּרְנוּ בְּכָל פִּנּוֹת, נֶהְפַּךְ מְחוֹלֵנוּ לְקִינוֹת, כִּי בְּשִׁבְעָה עָשָׂר בְּתַמּוּז בָּטְלוּ קָרְבָּנוֹת. סָרַרְנוּ לְפָנֶיךָ מֵרִיב לְשׁוֹנוֹת, לָכֵן לָמְדָה לְשׁוֹנֵנוּ לוֹמַר קִינוֹת, עֻזַּבְנוּ בְּלִי לְהִמָּנוֹת, כִּי בְּשִׁבְעָה עָשָׂר בְּתַמּוּז גָּרְמוּ לָנוּ עֲוׂנוֹת. פֻּזַּרְנוּ בְּלִי מְצוֹא רְוָחָה, לָכֵן רָבְתָה בָּנוּ אֲנָחָה, צוּר רְאֵה נַפְשֵׁנוּ כִּי שָׁחָה, וְשִׁבְעָה עָשָׂר בְּתַמּוּז הֲפָךְ לָנוּ לְשָׂשׂוֹן וּלְשִׂמְחָה. קִשִּׁינוּ עֹרֶף וְרָבְתָה בָּנוּ אָסוֹן, לָכֵן נִתַּנּוּ לִמְשִׁסָּה וְרִפְשׁוֹן, רְאֵה יהוה וְחַלְּצֵנוּ מֵאָסוֹן, וְשִׁבְעָה עָשָׂר בְּתַמּוּז הֲפָךְ לָנוּ לְשִׂמְחָה וּלְשָׂשׂוֹן. שְׁעֵנוּ שׁוֹכֵן רוּמָה, וְקַבֵּץ נְפוּצוֹתֵינוּ מִקַּצְווֹת אֲדָמָה, תֹּאמַר לְצִיּוֹן קוּמָה, וְשִׁבְעָה עָשָׂר בְּתַמּוּז הֲפָךְ לָנוּ לְיוֹם יְשׁוּעָה וְנֶחָמָה.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, מִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לְחַטָּאִים, וּסְלִיחָה לְפוֹשְׁעִים. עֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וָרוּחַ, לֹא כְרָעָתָם תִּגְמֹל. אֵל, הוֹרֵיתָ לָּנוּ לוֹמַר שְׁלֹשׁ עֶשְׂרֵה, וּזְכָר לָנוּ הַיּוֹם בְּרִית שְׁלשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָיו מִקֶּדֶם, כְּמוֹ שֶׁכָּתוּב: וַיֵּרֶד יהוה בֶּעָנָן, וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם, יהוה:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אֱלֹהִים, אַל דֳּמִי לָךְ, אַל תֶּחֱרַשׁ וְאַל תִּשְׁקוֹט אֵל: כִּי הִנֵּה אוֹיְבֶיךָ יֶהֱמָיוּן, וּמְשַׂנְאֶיךָ נָשְׂאוּ רֹאשׁ: אֵל נְקָמוֹת יהוה, אֵל נְקָמוֹת הוֹפִיעַ:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"כְּרַחֵם אָב עַל בָּנִים, כֵּן תְּרַחֵם יהוה עָלֵינוּ. לַיהוה הַיְּשׁוּעָה, עַל עַמְּךָ בִרְכָתֶךָ סֶּלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶּלָה: יהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֲמָרֵר בְּבֶכִי מִפְּנֵי יָד שְׁלוּחָה בְּעִי. בְּנַאֲצִי בְּתוֹךְ בֵּיתוֹ בְּבִגְדִי וְקָבְעִי. גָּח וּבָרַח וְנָסַע עֶשֶׂר וְעָלָה לַשְּׁבִיעִי. דִּמַּנִי הֱצִיקַנִי הִשִּׂיקַנִי בַּחֹדֶשׁ הָרְבִיעִי. הֵבִיא מוֹעֵד בִּמְלֵאָתוֹ לִשְׁבֹּר בַּחוּרֵי גִמּוּז. וְרִבָּה בוֹ פַעֲמַיִם בְּמִסְמוּס וּמִזְמוּז. זְבוּלוֹ כְּשָׁר שַׁאֲנַנּוֹת מְבַכּוֹת אֶת הַתַּמּוּז. חִיְּבַנִי וְאִיְּבַנִי אֲזַי בְּיֶרַח תַּמּוּז. טָמְנוּ פַחִים חֲמִשָּׁה בְּמִקְרָא תְּלָאוֹת מְשֻׁלָּחוֹת. יָכְלוּ לִי בְּשִׁבְעָה עָשָׂר בּוֹ בַּאֲלִיחוֹת. כִּי נוֹקַשְׁתִּי כְּכַלָּה עֲלוּבָה בְּחֻפַּת שַׁלְוָה וְהַצְלָחוֹת. לְרוֹעִי לֹא הִמְתַּנְתִּי שֵׁשׁ וְנִשְׁתַּבְּרוּ הַלֻּחוֹת. מִיָּדוֹ עָדִיתִי חֲלִי כֶתֶם, אֶצְעָדָה וְצָמִיד. נִגָּרוֹת בְּיוֹם אַפּוֹ, כְּשִׁחַתִּי דְרָכָי לְהַשְׁמִיד. סֵדֶר עֲבוֹדָתוֹ וְקַיִץ מִזְבְּחוֹ קַצְתִּי לְהַעֲמִיד. עַל כֵּן מִלִּשְׁכַּת הַטְּלָאִים בֻּטַּל הַתָּמִיד. פּוֹר הִתְפּוֹרְרָה וְנִתְפַּזְּרָה סוֹעֲרָה עֲנִיָּה. צִיָּה נִמְשְׁלָה מִבְּלִי חוֹבֵל, וְנִטְרְפָה כָּאֳנִיָּה. קַחְתָּהּ בְּחַטָּאתָהּ בְּרֹאשָׁהּ, וּבְכֶפֶל תַּאֲנִיָּה וַאֲנִיָּה. רִיבוּהָ צָרֶיהָ כְּהַיּוֹם וְהָבְקְעָה הָעִיר בַּשְּׁנִיָּה. שֻׁלְּחָה כִּצְבִי מֻדָּח מֵאֵין דּוֹרֵשׁ לְהַסְתִּירָה. שָׁנְנוּ לְשׁוֹנָם וּנְתָנוּהָ כְּשֶׂה, צַמְרָהּ וַחֲלָבָהּ לְהַתִּירָה. תִּצְעַק עַל כְּלִי חֶמְדָּה שֶׁבּוֹ נִכְתָּרָה. תַּחֲמוּד עֵינֶיהָ נֻצַּל כְּשָׂרַף אַפּוֹסְטְמוֹס הַתּוֹרָה. חֵרֵף עֲשׁוּקִים וּרְצוּצִים בַּעֲבוּר הַרְעִימָם סָכָל. יְרוּדִים בִּוְהָיָה לֶאֱכוֹל וּבְהַסְתֵּר פָּנִים מִלְּהִסְתַּכָּל. יָד הִשְׁלִים מִכְּנַף שִׁקּוּצִים נֶאֱכָל. עֵת צָרָה כְּהִתְכַּנֵּס וְהָעֳמַד צֶלֶם בְּהֵיכָל. דְּווּיִם סְגוּפִים בָּנִים הֶהָיוּ מִקֶּדֶם רִאשׁוֹנִים. סְמוּכוֹת צָרוֹתֵיהֶם זוֹ לְזוֹ כַּמֶּה שָׁנִים. לוֹקִים כַּאֲשֶׁר תַּעֲשֶׂינָה הַדְּבוֹרִים, וְהָעַקְרַבִּים שׁוֹנִים. הוֹגִים אָבַד שִׂבְרָם וּבָטֵל סִכּוּיָם בְּאִישׁוֹנִים. אֵל קַנָּא, בְּהִתְאַפֵּק בְּמַקְנִיאֶיךָ דְּשֵׁנִים רְטוּבִים. מְחַכִּים תָּקִים עוֹמְדִים לְעוֹלָמִים, כִּנְטִיעִים מְחֻטָּבִים בַּאֲהָבִים. הָאֱמֶת וְהַשָּׁלוֹם בְּצוֹמוֹת חֲטוּבִים. נֶצַח הֱיוֹתָם לְשִׂמְחָה וּלְשָׂשׂוֹן וּלְמוֹעֲדִים טוֹבִים.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, מִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לְחַטָּאִים, וּסְלִיחָה לְפוֹשְׁעִים. עֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וָרוּחַ, לֹא כְרָעָתָם תִּגְמֹל. אֵל, הוֹרֵיתָ לָּנוּ לוֹמַר שְׁלֹשׁ עֶשְׂרֵה, וּזְכָר לָנוּ הַיּוֹם בְּרִית שְׁלשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָיו מִקֶּדֶם, כְּמוֹ שֶׁכָּתוּב: וַיֵּרֶד יהוה בֶּעָנָן, וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם, יהוה:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"פזמון. שליח הציבור אומר את הבית הראשון, והקהל חוזר אחריו, ולאחר מכן כל בית הקהל אומר ושליח הציבור חוזר.","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"שְׁעֵה נֶאֱסַר, אֲשֶׁר נִמְסַר, בְּיַד בָּבֶל וְגַם שֵׂעִיר. לְךָ יֶהֱמֶה, זֶה כַּמֶּה, וְיִתְחַנֵּן כְּבֶן צָעִיר.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"יוֹם גָּבַר הָאוֹיֵב וַתִּבָּקַע הָעִיר.","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"לְזֹאת אִכַּף, וְאֶסְפֹּק כַּף, בְּיוֹם חִמֵּשׁ פִּזְרוֹנִי. וְעַל רֶגֶל הָעֵגֶל, הַלּוּחוֹת יְצָאוּנִי. וְגַם הִשְׁמִיד הַתָּמִיד, וּבַסּוּגַר הֱבִיאַנִי. וְהוּשַׂם אֱלִיל בְּהֵיכַל כְּלִיל, וּמֵעֲצָתוֹ כְּלָאַנִי. וְהַמִּנְחָה הוּנָחָה, וְדָתְךָ, צָר בָּאֵשׁ הִבְעִיר.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"יוֹם גָּבַר הָאוֹיֵב וַתִּבָּקַע הָעִיר.","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"מְאֹד אֶתְחַל, וָאֶתְחַלְחַל, בְּיוֹם שַׁדַּי דְּחָפַנִי. וְהַשְּׁפִיפוֹן מִצָּפוֹן, כְּשִׁבֹּלֶת שְׁטָפַנִי. מְאוֹר חָשַׁךְ, וְגַם שֵׁשַׁךְ, כְּמוֹ כַּדּוּר צְנָפַנִי. וְהַצַּיָּד שָׁלַח יָד, וְהַצָּפִיר וְהַשָּׂעִיר.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"יוֹם גָּבַר הָאוֹיֵב וַתִּבָּקַע הָעִיר.","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"הוֹד לִבִּי וּמִשְׂגַּבִּי, הֲלָעַד אַפְּךָ יֶעְשַׁן. הֲלֹא תִרְאֶה עַם נִלְאֶה, אֲשֶׁר הָשְׁחַר כְּמוֹ כִבְשָׁן. גְּדֹר פִּרְצִי בְּבֶן פַּרְצִי, וּמֵחֶדֶק לְקֹט שׁוֹשָׁן. בְּנֵה בֵּית זְבוּל, וְהָשֵׁב גְּבוּל הַכַּרְמֶל וְהַבָּשָׁן. וְעַיִן פְּקַח, וְנָקָם קַח מֵאֵצֶר וּמִדִּישָׁן. שְׁפֹט אִלֵּם, וְאָז יְשַׁלֵּם הַמַּבְעֶה וְהַמַּבְעִיר.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"יוֹם גָּבַר הָאוֹיֵב וַתִּבָּקַע הָעִיר.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, מִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לְחַטָּאִים, וּסְלִיחָה לְפוֹשְׁעִים. עֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וָרוּחַ, לֹא כְרָעָתָם תִּגְמֹל. אֵל, הוֹרֵיתָ לָּנוּ לוֹמַר שְׁלֹשׁ עֶשְׂרֵה, וּזְכָר לָנוּ הַיּוֹם בְּרִית שְׁלשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָיו מִקֶּדֶם, כְּמוֹ שֶׁכָּתוּב: וַיֵּרֶד יהוה בֶּעָנָן, וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם, יהוה:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"זְכֹר רַחֲמֶיךָ יהוה וַחֲסָדֶיךָ, כִּי מֵעוֹלָם הֵמָּה: זָכְרֵנוּ יהוה בִּרְצוֹן עַמֶּךָ, פָּקְדֵנוּ בִּישׁוּעָתֶךָ. זְכֹר עֲדָתְךָ קָנִיתָ קֶדֶם, גָּאַלְתָּ שֵׁבֶט נַחֲלָתֶךָ, הַר צִיּוֹן זֶה שָׁכַנְתָּ בּוֹ: זְכֹר יהוה חִבַּת יְרוּשָׁלָיִם, אַהֲבַת צִיּוֹן אַל תִּשְׁכַּח לָנֶצַח. אַתָּה תָקוּם תְּרַחֵם צִיּוֹן, כִּי עֵת לְחֶנְנָהּ, כִּי בָא מוֹעֵד: זְכֹר יהוה לִבְנֵי אֱדוֹם אֵת יוֹם יְרוּשָׁלָיִם, הָאוֹמְרִים עָרוּ עָרוּ, עַד הַיְסוֹד בָּהּ: זְכֹר לְאַבְרָהָם לְיִצְחָק וּלְיִשְׂרָאֵל עֲבָדֶיךָ, אֲשֶׁר נִשְׁבַּעְתָּ לָהֶם בָּךְ, וַתְּדַבֵּר אֲלֵהֶם, אַרְבֶּה אֶת זַרְעֲכֶם כְּכוֹכְבֵי הַשָּׁמַיִם, וְכָל הָאָרֶץ הַזֹּאת אֲשֶׁר אָמַרְתִּי אֶתֵּן לְזַרְעֲכֶם, וְנָחֲלוּ לְעוֹלָם: זְכֹר לַעֲבָדֶיךָ לְאַבְרָהָם לְיִצְחָק וּלְיַעֲקֹב, אַל תֵּפֶן אֶל קְשִׁי הָעָם הַזֶּה וְאֶל רִשְׁעוֹ וְאֶל חַטָּאתוֹ:\n\nאַל נָא תָשֵׁת עָלֵינוּ חַטָּאת אֲשֶׁר נוֹאַלְנוּ וַאֲשֶׁר חָטָאנוּ: חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"יש המוסיפים פיוט זה ואומרים אותו בית בית עם שליח הציבור:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אֵל נָא, רְפָא נָא תַּחֲלוּאֵי גֶפֶן פּוֹרִיָּה, בּוֹשָׁה וַחֲפוּרָה וְאֻמְלַל פִּרְיָהּ, גְּאָלֶנָּה מִשַּׁחַת וּמִמַּכָּה טְרִיָּה, עֲנֵנוּ כְּשֶׁעָנִיתָ לְאַבְרָהָם אָבִינוּ בְּהַר הַמּוֹרִיָּה.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"דִּגְלֵי עָם פְּדוּיֵי בִּזְרוֹעַ חָשׂוּף, הַצֵּל מִנֶּגֶף וְאַל יִהְיוּ לְשִׁסּוּף, וְתַעֲנֶה קְרִיאָתֵנוּ וּלְמַעֲשֵׂה יָדֶיךָ תִּכְסֹף, עֲנֵנוּ כְּשֶׁעָנִיתָ לַאֲבוֹתֵינוּ עַל יַם סוּף.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"זְכוּת צוּר חֻצַּב הַיּוֹם לָנוּ תְגַל, חָשְׂכֵנוּ מֵאֶנֶף וּנְחֵנוּ בְּיֹשֶׁר מַעְגָּל, טַהֵר טֻמְאָתֵנוּ וְלִמְאוֹר תּוֹרָתְךָ עֵינֵינוּ גַל, עֲנֵנוּ כְּשֶׁעָנִיתָ לִיהוֹשֻׁעַ בַּגִּלְגָּל.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"יָהּ, רְאֵה דֶשֶׁן עָקוּד וְהַצְמַח לָנוּ תְרוּפָה, כַּלֵּה שׁוֹד וָשֶׁבֶר, סַעַר וְסוּפָה, לַמְּדֵנוּ וְחַכְּמֵנוּ אִמְרָתְךָ הַצְּרוּפָה, עֲנֵנוּ כְּשֶׁעָנִיתָ לִשְׁמוּאֵל בַּמִּצְפָּה.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"מֻתְמָם מֵרֶחֶם שָׁרָשָׁיו אַל תַּקְמֵל, נַקֵּנוּ מִכֶּתֶם וְשֶׁמֶץ וְלֹא נֵאָמֵל, סְעָדֵנוּ וְנִוָּשֵׁעָה וְאָרְחוֹת חֲסָדֶיךָ נִגָּמֵל, עֲנֵנוּ כְּשֶׁעָנִיתָ לְאֵלִיָּהוּ בְּהַר הַכַּרְמֶל.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"עוֹדְדֵנוּ בְּצֶדֶק מָשׁוּי מִמַּיִם וְכַפֵּר זָדוֹן וּמְשׁוּגָה, פְּדֵנוּ מִמְּהוּמַת מָוֶת וְאָחוֹר בַּל נִסּוֹגָה, צַוֵּה יְשׁוּעָתֵנוּ וּבַעֲוׂנוֹתֵינוּ אַל נִתְמוֹגְגָה, עֲנֵנוּ כְּשֶׁעָנִיתָ לְיוֹנָה בִּמְעֵי הַדָּגָה.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"קְדֻשַּׁת אִישׁ חֲסִידֶךָ זְכֹר לִיפַת פַּעֲמַיִם, רַחֲמֶיךָ תְּעוֹרֵר כִּי לָקִינוּ בְּכִפְלַיִם, שׁוּבֵנוּ תֹּקֶף לְיִרְאָתֶךָ וְלֹא נֵחָשֵׂף שׁוּלַיִם, עֲנֵנוּ כְּשֶׁעָנִיתָ לְדָוִד וְלִשְׁלֹמֹה בְנוֹ בִּירוּשָׁלַיִם.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"בתענית אסתר יש מוסיפים:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"תַּעֲנֶה לְקוֹרְאֶיךָ וְהַסְכֵּת מִמְּעוֹנִים, תִּשְׁמַע שַׁוְעַת צוֹעֲקֶיךָ, שׁוֹמֵעַ אֶל אֶבְיוֹנִים, תְּרַחֵם עַל בָּנֶיךָ כְּרַחֵם אָב עַל בָּנִים, עֲנֵנוּ כְּמוֹ שֶׁעָנִיתָ לְמָרְדְּכַי וְאֶסְתֵּר, וְתָלוּ עַל עֵץ חֲמִשִּׁים הָאָב עִם הַבָּנִים.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"מכאן כולם אומרים:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"זְכֹר לָנוּ בְּרִית אָבוֹת כַּאֲשֶׁר אָמַרְתָּ: וְזָכַרְתִּי אֶת בְּרִיתִי יַעֲקוֹב וְאַף אֶת בְּרִיתִי יִצְחָק וְאַף אֶת בְּרִיתִי אַבְרָהָם אֶזְכֹּר, וְהָאָרֶץ אֶזְכֹּר:\n\nזְכֹר לָנוּ בְּרִית רִאשׁוֹנִים כַּאֲשֶׁר אָמַרְתָּ: וְזָכַרְתִּי לָהֶם בְּרִית רִאשׁוֹנִים אֲשֶׁר הוֹצֵאתִי אוֹתָם מֵאֶרֶץ מִצְרַיִם לְעֵינֵי הַגּוֹיִם לִהְיוֹת לָהֶם לֵאלֹהִים, אֲנִי יהוה:\n\nעֲשֵׂה עִמָּנוּ כְּמָה שֶׁהִבְטַחְתָּנוּ: וְאַף גַּם זֹאת בִּהְיוֹתָם בְּאֶרֶץ אוֹיְבֵיהֶם לֹא מְאַסְתִּים וְלֹא גְעַלְתִּים לְכַלּוֹתָם לְהָפֵר בְּרִיתִי אִתָּם, כִּי אֲנִי יהוה אֱלֹהֵיהֶם: הָשֵׁב שְׁבוּתֵנוּ וְרַחֲמֵנוּ כְּמָה שֶׁכָּתוּב: וְשָׁב יהוה אֱלֹהֶיךָ אֶת שְׁבוּתְךָ וְרִחֲמֶךָ, וְשָׁב וְקִבֶּצְךָ מִכָּל הָעַמִּים אֲשֶׁר הֱפִיצְךָ יהוה אֱלֹהֶיךָ שָׁמָּה: קַבֵּץ נִדָּחֵינוּ כְּמָה שֶׁכָּתוּב: אִם יִהְיֶה נִדַּחֲךָ בִּקְצֵה הַשָּׁמָיִם, מִשָּׁם יְקַבֶּצְךָ יהוה אֱלֹהֶיךָ וּמִשָּׁם יִקָּחֶךָ: מְחֵה פְשָׁעֵינוּ כָּעָב וְכֶעָנָן כְּמָה שֶׁכָּתוּב: מָחִיתִי כָעָב פְּשָׁעֶיךָ וְכֶעָנָן חַטֹּאתֶיךָ, שׁוּבָה אֵלַי כִּי גְאַלְתִּיךָ: מְחֵה פְשָׁעֵינוּ לְמַעַנְךָ כַּאֲשֶׁר אָמַרְתָּ: אָנֹכִי אָנֹכִי הוּא מֹחֶה פְשָׁעֶיךָ לְמַעֲנִי, וְחַטֹּאתֶיךָ לֹא אֶזְכֹּר: הַלְבֵּן חֲטָאֵינוּ כַּשֶּׁלֶג וְכַצֶּמֶר כְּמָה שֶׁכָּתוּב: לְכוּ נָא וְנִוָּכְחָה יֹאמַר יהוה, אִם יִהְיוּ חֲטָאֵיכֶם כַּשָּׁנִים כַּשֶּׁלֶג יַלְבִּינוּ, אִם יַאְדִּימוּ כַתּוֹלָע כַּצֶּמֶר יִהְיוּ: זְרֹק עָלֵינוּ מַיִם טְהוֹרִים וְטַהֲרֵנוּ כְּמָה שֶׁכָּתוּב: וְזָרַקְתִּי עֲלֵיכֶם מַיִם טְהוֹרִים וּטְהַרְתֶּם, מִכֹּל טֻמְאֹתֵיכֶם וּמִכָּל גִּלּוּלֵיכֶם אֲטַהֵר אֶתְכֶם: רַחֵם עָלֵינוּ וְאַל תַּשְׁחִיתֵנוּ כְּמָה שֶׁכָּתוּב: כִּי אֵל רַחוּם יהוה אֱלֹהֶיךָ, לֹא יַרְפְּךָ וְלֹא יַשְׁחִיתֶךָ, וְלֹא יִשְׁכַּח אֶת בְּרִית אֲבֹתֶיךָ אֲשֶׁר נִשְׁבַּע לָהֶם: מוֹל אֶת לְבָבֵנוּ לְאַהֲבָה אֶת שְׁמֶךָ כְּמָה שֶׁכָּתוּב: וּמָל יהוה אֱלֹהֶיךָ אֶת לְבָבְךָ וְאֶת לְבַב זַרְעֶךָ, לְאַהֲבָה אֶת יהוה אֱלֹהֶיךָ בְּכָל לְבָבְךָ וּבְכָל נַפְשְׁךָ, לְמַעַן חַיֶּיךָ: הִמָּצֵא לָנוּ בְּבַקָּשָׁתֵנוּ כְּמָה שֶׁכָּתוּב: וּבִקַּשְׁתֶּם מִשָּׁם אֶת יהוה אֱלֹהֶיךָ וּמָצָאתָ, כִּי תִדְרְשֶׁנּוּ בְּכָל לְבָבְךָ וּבְכָל נַפְשֶׁךָ: תְּבִיאֵנוּ אֶל הַר קָדְשֶׁךָ וְשַׂמְּחֵנוּ בְּבֵית תְּפִלָּתֶךָ כְּמָה שֶׁכָּתוּב: וַהֲבִיאוֹתִים אֶל הַר קָדְשִׁי וְשִׂמַּחְתִּים בְּבֵית תְּפִלָּתִי, עוֹלוֹתֵיהֶם וְזִבְחֵיהֶם לְרָצוֹן עַל מִזְבְּחִי, כִּי בֵיתִי, בֵּית תְּפִלָּה יִקָּרֵא לְכָל הָעַמִּים:","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"פותחים את ארון הקודש ואמורים משפט משפט. יש קהילות בהם סדר המשפטים שונה וברוב הקהילות מדלגים על המשפט \"יהיו לרצון\".","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"שְׁמַע קוֹלֵנוּ, יהוה אֱלֹהֵינוּ, חוּס וְרַחֵם עָלֵינוּ, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ. הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם: אֲמָרֵינוּ הַאֲזִינָה יהוה, בִּינָה הֲגִיגֵנוּ. יִהְיוּ לְרָצוֹן אִמְרֵי פִינוּ וְהֶגְיוֹן לִבֵּנוּ לְפָנֶיךָ, יהוה צוּרֵנוּ וְגוֹאֲלֵנוּ. אַל תַּשְׁלִיכֵנוּ מִלְּפָנֶיךָ, וְרוּחַ קָדְשְׁךָ אַל תִּקַּח מִמֶּנּוּ. אַל תַּשְׁלִיכֵנוּ לְעֵת זִקְנָה, כִּכְלוֹת כֹּחֵנוּ אַל תַּעַזְבֵנוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"מכאן מפסיקים לומר עם החזן בקול.","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אַל תַּעַזְבֵנוּ יהוה, אֱלֹהֵינוּ אַל תִּרְחַק מִמֶּנוּ. עֲשֵׂה עִמָּנוּ אוֹת לְטוֹבָה, וְיִרְאוּ שׂוֹנְאֵינוּ וְיֵבוֹשׁוּ, כִּי אַתָּה יהוה עֲזַרְתָּנוּ וְנִחַמְתָּנוּ. כִּי לְךָ יהוה הוֹחָלְנוּ, אַתָּה תַעֲנֶה אֲדֹנָי אֱלֹהֵינוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"סוגרים את ארון הקודש.","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, תָּבוֹא לְפָנֶיךָ תְּפִלָּתֵנוּ וְאַל תִּתְעַלַּם מִתְּחִנָּתֵנוּ, שֶׁאֵין אָנוּ עַזֵּי פָנִים וּקְשֵׁי עֹרֶף לוֹמַר לְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ צַדִּיקִים אֲנַחְנוּ וְלֹא חָטָאנוּ, אֲבָל אֲנַחְנוּ וַאֲבוֹתֵינוּ חָטָאנוּ.\nאָשַׁמְנוּ, בָּגַדְנוּ, גָּזַלְנוּ, דִּבַּרְנוּ דֹפִי. הֶעֱוִינוּ, וְהִרְשַׁענוּ, זַדְנוּ, חָמַסְנוּ, טָפַלְנוּ שֶׁקֶר. יָעַצְנוּ רָע, כְּזַּבְנוּ, לַצְנוּ, מָרַדְנוּ, נִאַצְנוּ, סָרַרְנוּ, עָוְינוּ, פָּשַׁעְנוּ, צָרַרְנוּ, קִשִּׁינוּ עֹרֶף. רָשַׁעְנוּ, שִׁחַתְנוּ, תִּעַבְנוּ, תָּעִינוּ, תִּעְתַּעְנוּ.\nסַרְנוּ מִמִּצְוׂתֶיךָ וּמִמִּשְׁפָּטֶיךָ הַטּוֹבִים וְלֹא שָׁוָה-לָנוּ. וְאַתָּה צַדִּיק עַל כָּל הַבָּא עָלֵינוּ, כִּי אֱמֶת עָשִׂיתָ, וַאֲנַחְנוּ הִרְשָׁעְנוּ:\n\nהִרְשַׁעְנוּ וּפָשַׁעְנוּ לָכֵן לֹא נוֹשָׁעְנוּ. וְתֵן בְּלִבֵּנוּ לַעֲזֹב דֶּרֶךְ רֶשַׁע, וְחִישׁ לָנוּ יֶשַׁע, כַּכָּתוּב עַל יַד נְבִיאֶךָ: יַעֲזוֹב רָשָׁע דַּרְכּוֹ וְאִישׁ אָוֶן מַחְשְׁבֹתָיו, וְיָשֹׁב אֶל יהוה וִירַחֲמֵהוּ, וְאֶל אֱלֹהֵינוּ כִּי יַרְבֶּה לִסְלוֹחַ:\n\nמְשִׁיחַ צִדְקֶךָ אָמַר לְפָנֶיךָ: שְׁגִיאוֹת מִי יָבִין מִנִּסְתָּרוֹת נַקֵּנִי: נַקֵּנוּ יהוה אֱלֹהֵינוּ מִכָּל פְּשָׁעֵינוּ וְטַהֲרֵנוּ מִכָּל טֻמְאוֹתֵינוּ, וּזְרֹק עָלֵינוּ מַיִם טְהוֹרִים וְטַהֲרֵנוּ, כַּכָּתוּב עַל יַד נְבִיאֶךָ: וְזָרַקְתִּי עֲלֵיכֶם מַיִם טְהוֹרִים וּטְהַרְתֶּם, מִכֹּל טֻמְאוֹתֵיכֶם וּמִכָּל גִּלּוּלֵיכֶם אֲטַהֵר אֶתְכֶם: עַמְּךָ וְנַחֲלָתְךָ רְעֵבֵי טוּבְךָ, צְמֵאֵי חַסְדְּךָ, תְּאֵבֵי יִשְׁעֶךָ. יַכִּירוּ וְיֵדְעוּ כִּי לַיהוה אֱלֹהֵינוּ הָרַחֲמִים וְהַסְּלִיחוֹת.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"אם אין אומרים תחנון מדלגים על המשך הסליחות.","cond":["shacharitTachanun","17tammuz","shacharitTachanun"]},{"kind":"text","text":"אֵל רַחוּם שְׁמֶךָ. אֵל חַנּוּן שְׁמֶךָ. בָּנוּ נִקְרָא שְׁמֶךָ. יהוה עֲשֵׂה לְמַעַן שְׁמֶךָ. עֲשֵׂה לְמַעַן אֲמִתָּךְ. עֲשֵׂה לְמַעַן בְּרִיתָךְ. עֲשֵׂה לְמַעַן גָּדְלָךְ וְתִפְאַרְתָּךְ. עֲשֵׂה לְמַעַן דָּתָךְ. עֲשֵׂה לְמַעַן הוֹדָךְ. עֲשֵׂה לְמַעַן וִעוּדָךְ. עֲשֵׂה לְמַעַן זִכְרָךְ. עֲשֵׂה לְמַעַן חַסְדָּךְ. עֲשֵׂה לְמַעַן טוּבָךְ. עֲשֵׂה לְמַעַן יִחוּדָךְ. עֲשֵׂה לְמַעַן כְּבוֹדָךְ. עֲשֵׂה לְמַעַן לִמּוּדָךְ. עֲשֵׂה לְמַעַן מַלְכוּתָךְ. עֲשֵׂה לְמַעַן נִצְחָךְ. עֲשֵׂה לְמַעַן סוֹדָךְ. עֲשֵׂה לְמַעַן עֻזָּךְ. עֲשֵׂה לְמַעַן פְּאֵרָךְ. עֲשֵׂה לְמַעַן צִדְקָתָךְ. עֲשֵׂה לְמַעַן קְדֻשָׁתָךְ. עֲשֵׂה לְמַעַן רַחֲמֶיךָ הָרַבִּים. עֲשֵׂה לְמַעַן שְׁכִינָתָךְ. עֲשֵׂה לְמַעַן תְּהִלָּתָךְ. עֲשֵׂה לְמַעַן אוֹהֲבֶיךָ שׁוֹכְנֵי עָפָר. עֲשֵׂה לְמַעַן אַבְרָהָם יִצְחָק וְיַעֲקֹב. עֲשֵׂה לְמַעַן מֹשֶׁה וְאַהֲרֹן. עֲשֵׂה לְמַעַן דָּוִד וּשְׁלֹמֹה. עֲשֵׂה לְמַעַן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ. עֲשֵׂה לְמַעַן צִיּוֹן מִשְׁכַּן כְּבוֹדֶךָ. עֲשֵׂה לְמַעַן שִׁמְמוֹת הֵיכָלֶךָ. עֲשֵׂה לְמַעַן הֲרִיסוּת מִזְבְּחֶךָ. עֲשֵׂה לְמַעַן הֲרוּגִים עַל שֵׁם קָדְשֶׁךָ. עֲשֵׂה לְמַעַן טְבוּחִים עַל יִחוּדֶךָ. עֲשֵׂה לְמַעַן בָּאֵי בָאֵשׁ וּבַמַּיִם עַל קִדּוּשׁ שְׁמֶךָ. עֲשֵׂה לְמַעַן יוֹנְקֵי שָׁדַיִם שֶׁלֹּא חָטְאוּ. עֲשֵׂה לְמַעַן גְּמוּלֵי חָלָב שֶׁלֹּא פָשְׁעוּ. עֲשֵׂה לְמַעַן תִּינוֹקוֹת שֶׁל בֵּית רַבָּן. עֲשֵׂה לְמַעַנְךָ אִם לֹא לְמַעֲנֵנוּ. עֲשֵׂה לְמַעַנְךָ וְהוֹשִׁיעֵנוּ.\n\nעֲנֵנוּ יהוה עֲנֵנוּ. עֲנֵנוּ אֱלֹהֵינוּ עֲנֵנוּ. עֲנֵנוּ אָבִינוּ עֲנֵנוּ. עֲנֵנוּ בּוֹרְאֵנוּ עֲנֵנוּ. עֲנֵנוּ גּוֹאֲלֵנוּ עֲנֵנוּ. עֲנֵנוּ דּוֹרְשֵׁנוּ עֲנֵנוּ. עֲנֵנוּ הָאֵל הַנֶּאֱמָן עֲנֵנוּ. עֲנֵנוּ וָתִיק וְחָסִיד עֲנֵנוּ. עֲנֵנוּ זַךְ וְיָשָׁר עֲנֵנוּ. עֲנֵנוּ חַי וְקַיָּם עֲנֵנוּ. עֲנֵנוּ טוֹב וּמֵטִיב עֲנֵנוּ. עֲנֵנוּ יוֹדֵעַ יֶצֶר עֲנֵנוּ. עֲנֵנוּ כּוֹבֵשׁ כְּעָסִים עֲנֵנוּ. עֲנֵנוּ לוֹבֵשׁ צְדָקוֹת עֲנֵנוּ. עֲנֵנוּ מֶלֶךְ מַלְכֵי הַמְּלָכִים עֲנֵנוּ. עֲנֵנוּ נוֹרָא וְנִשְׂגָּב עֲנֵנוּ. עֲנֵנוּ סוֹלֵחַ וּמוֹחֵל עֲנֵנוּ. עֲנֵנוּ עוֹנֶה בְּעֵת צָרָה עֲנֵנוּ. עֲנֵנוּ פּוֹדֶה וּמַצִּיל עֲנֵנוּ. עֲנֵנוּ צַדִּיק וְיָשָׁר עֲנֵנוּ. עֲנֵנוּ קָרוֹב לְקוֹרְאָיו עֲנֵנוּ. עֲנֵנוּ רַחוּם וְחַנוּן עֲנֵנוּ. עֲנֵנוּ שׁוֹמֵעַ אֶל אֶבְיוֹנִים עֲנֵנוּ. עֲנֵנוּ תּוֹמֵךְ תְּמִימִים עֲנֵנוּ. עֲנֵנוּ אֱלֹהֵי אֲבוֹתֵינוּ עֲנֵנוּ. עֲנֵנוּ אֱלֹהֵי אַבְרָהָם עֲנֵנוּ. עֲנֵנוּ פַּחַד יִצְחָק עֲנֵנוּ. עֲנֵנוּ אֲבִיר יַעֲקֹב עֲנֵנוּ. עֲנֵנוּ עֶזְרַת הַשְּׁבָטִים עֲנֵנוּ. עֲנֵנוּ מִשְׂגַּב אִמָּהוֹת עֲנֵנוּ. עֲנֵנוּ קָשֶׁה לִכְעוֹס עֲנֵנוּ. עֲנֵנוּ רַךְ לִרְצוֹת עֲנֵנוּ. עֲנֵנוּ עוֹנֶה בְּעֵת רָצוֹן עֲנֵנוּ. עֲנֵנוּ אֲבִי יְתוֹמִים עֲנֵנוּ. עֲנֵנוּ דַּיַּן אַלְמָנוֹת עֲנֵנוּ.\n\nמִי שֶׁעָנָה לְאַבְרָהָם אָבִינוּ בְּהַר הַמּוֹרִיָּה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְיִצְחָק בְּנוֹ כְּשֶׁנֶּעֱקַד עַל גַּבֵּי הַמִּזְבֵּחַ הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְיַעֲקֹב בְּבֵית אֵל הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְיוֹסֵף בְּבֵית הָאֲסוּרִים הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לַאֲבוֹתֵינוּ עַל יַם סוּף הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְמֹשֶׁה בְּחוֹרֵב הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְאַהֲרֹן בַּמַּחְתָּה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְפִינְחָס בְּקוּמוֹ מִתּוֹךְ הָעֵדָה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לִיהוֹשֻׁעַ בַּגִּלְגָּל הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לִשְׁמוּאֵל בַּמִּצְפָּה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְדָוִד וּשְׁלֹמֹה בְנוֹ בִּירוּשָׁלָיִם הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְאֵלִיָּהוּ בְּהַר הַכַּרְמֶל הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לֶאֱלִישָׁע בִּירִיחוֹ הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְיוֹנָה בִּמְעֵי הַדָּגָה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְחִזְקִיָּהוּ מֶלֶךְ יְהוּדָה בְּחָלְיוֹ הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לַחֲנַנְיָה מִישָׁאֵל וַעֲזַרְיָה בְּתוֹךְ כִּבְשַׁן הָאֵשׁ הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְדָנִיֵּאל בְּגוֹב הָאֲרָיוֹת הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְמָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְעֶזְרָא בַּגּוֹלָה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְכָל הַצַּדִּיקִים וְהַחֲסִידִים וְהַתְּמִימִים וְהַיְּשָׁרִים הוּא יַעֲנֵנוּ.\n\nרַחֲמָנָא דְעָנֵי לַעֲנִיֵי עֲנֵינָא. רַחֲמָנָא דְעָנֵי לִתְבִירֵי לִבָּא עֲנֵינָן. רַחֲמָנָא דְעָנֵי לְמַכִּיכֵי רוּחָא עֲנֵינָן. רַחֲמָנָא עֲנֵינָן. רַחֲמָנָא חוּס. רַחֲמָנָא פְּרוֹק. רַחֲמָנָא שְׁזִיב. רַחֲמָנָא רְחַם עֲלָן. הַשְׁתָּא בַּעֲגָלָא וּבִזְמַן קָרִיב.","cond":["shacharitTachanun","17tammuz","shacharitTachanun"]},{"kind":"header","text":"סליחות לעשרה בטבת","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"סליחות לעשרה בטבת","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"סְלַח לָנוּ אָבִינוּ כִּי בְּרֹב אִוַּלְתֵּנוּ שָׁגִינוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי רַבּוּ עֲוׂנֵינוּ.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אֵל אֶרֶךְ אַפַּיִם אַתָּה וּבַעַל הָרַחֲמִים נִקְרֵאתָ, וְדֶרֶךְ תְּשׁוּבָה הוֹרֵיתָ, גְּדֻלַּת רַחֲמֶיךָ וַחֲסָדֶיךָ תִּזְכֹּר הַיּוֹם וּבְכָל יוֹם לְזֶרַע יְדִידֶיךָ. תֵּפֶן אֵלֵינוּ בְּרַחֲמִים, כִּי אַתָּה הוּא בַּעַל הָרַחֲמִים. בְּתַחֲנוּן וּבִתְפִלָּה פָּנֶיךָ נְקַדֵּם, כְּהוֹדַעתָּ לֶעָנָו מִקֶּדֶם. מֵחֲרוֹן אַפְּךָ שׁוּב, כְּמוֹ בְּתוֹרָתְךָ כָּתוּב. וּבְצֵל כְּנָפֶיךָ נֶחְסֶה וְנִתְלוֹנָן, כְּיוֹם וַיֵּרֶד יהוה בֶּעָנָן. תַּעֲבֹר עַל פֶּשַׁע וְתִמְחֶה אָשָׁם, כְּיוֹם וַיִּתְיַצֵּב עִמּוֹ שָׁם. תַּאֲזִין שַׁוְעָתֵנוּ וְתַקְשִׁיב מֶנּוּ מַאֲמָר, כְּיוֹם וַיִּקְרָא בְשֵׁם יהוה, וְשָׁם נֶאֲמַר:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"כִּי עִם יהוה הַחֶסֶד, וְהַרְבֵּה עִמּוֹ פְדוּת: פְּדֵה אֱלֹהִים אֶת יִשְׂרָאֵל מִכֹּל צָרוֹתָיו: וְהוּא יִפְדֶּה אֶת יִשְׂרָאֵל מִכֹּל עֲוׂנוֹתָיו: פּוֹדֶה יהוה נֶפֶשׁ עֲבָדָיו, וְלֹא יֶאְשְׁמוּ כָּל הַחוֹסִים בּוֹ:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"כְּרַחֵם אָב עַל בָּנִים, כֵּן תְּרַחֵם יהוה עָלֵינוּ. לַיהוה הַיְּשׁוּעָה, עַל עַמְּךָ בִרְכָתֶךָ סֶּלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶּלָה: יהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"סְלַח נָא לַעֲוׂן הָעָם הַזֶּה כְּגֹדֶל חַסְדֶּךָ, וְכַאֲשֶׁר נָשָׂאתָה לָעָם הַזֶּה מִמִּצְרַיִם וְעַד הֵנָּה: וְשָׁם נֶאֱמַר:","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"קהל ואחריו שליח הציבור:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"וַיֹּאמֶר יהוה: סָלַחְתִּי כִּדְבָרֶךָ:\n\nהַטֵּה אֱלֹהַי אָזְנְךָ וּשֲׁמָע, פְּקַח עֵינֶיךָ וּרְאֵה שׁוֹמְמוֹתֵינוּ וְהָעִיר אֲשֶׁר נִקְרָא שִׁמְךָ עָלֶיהָ, כִּי לֹא עַל צִדְקוֹתֵינוּ אֲנַחְנוּ מַפִּילִים תַּחֲנוּנֵינוּ לְפָנֶיךָ, כִּי עַל רַחֲמֶיךָ הָרַבִּים: אֲדֹנָי שְׁמָעָה, אֲדֹנָי סְלָחָה, אֲדֹנָי הַקְשִׁיבָה וַעֲשֵׂה אַל תְּאַחַר, לְמַעַנְךָ אֱלֹהַי, כִּי שִׁמְךָ נִקְרָא עַל עִירְךָ וְעַל עַמֶּךָ:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֶזְכְּרָה מָצוֹק אֲשֶׁר קְרָאַנִי, בְּשָׁלֹשׁ מַכּוֹת בַּחֹדֶשׁ הַזֶּה הִכַּנִי, גִּדְּעַנִי הֱנִיאַנִי הִכְאַנִי, אַךְ עַתָּה הֶלְאָנִי. דִּעֲכַנִי בִּשְׁמוֹנָה בוֹ שְׂמָאלִית וִימָנִית, הֲלֹא שְׁלָשְׁתָּן קָבַעְתִּי תַעֲנִית, וּמֶלֶךְ יָוָן אֲנָסַנִי לִכְתֹּב דָּת יְוָנִית, עַל גַּבִּי חָרְשׁוּ חוֹרְשִׁים, הֶאֱרִיכוּ מַעֲנִית. זוֹעַמְתִּי בְּתִשְׁעָה בוֹ בִּכְלִמָה וָחֵפֶר, חָשַׂךְ מֵעָלַי מְעִיל הוֹד וָצֶפֶר, טָרֹף טֹרַף בּוֹ הַנּוֹתֵן אִמְרֵי שֶׁפֶר, הוּא עֶזְרָא הַסּוֹפֵר. יוֹם עֲשִׂירִי צֻוָּה בֶּן בּוּזִי הַחוֹזֶה, כְּתָב לְךָ בְּסֵפֶר הַמַּחֲזֶה, לְזִכָּרוֹן לְעַם נָמֵס וְנִבְזֶה, אֶת עֶצֶם הַיּוֹם הַזֶּה. מִנְיַן סֵדֶר חֳדָשִׁים בַּעֲשָׂרָה בוֹ הֵעִיר, נְהִי וִילֵל בְּמוֹ פִי אַפְעִיר, סֵדֶר פֻּרְעָנֻיּוֹת בְּתוֹךְ לְבָבִי יַבְעִיר, בְּבֹא אֵלַי הַפָּלִיט לֵאמֹר הֻכְּתָה הָעִיר. עַל אֵלֶּה עַל פָּנַי אָבָק זֵרִיתִי, פַּצְתִּי עַל אַרְבַּעְתָּן לוּ חֵץ בְּלִבִּי יָרִיתִי, צָרוֹת עַל אֵלֶּה קֶבֶר לִי כָּרִיתִי. צַדִּיק הוּא יהוה כִּי פִיהוּ מָרִיתִי, קָרָאתִי שִׁמְךָ מִתְנַחֵם עַל רָעָתִי, רְאֵה עָנְיִי וּשְׁמַע קוֹל פְּגִיעָתִי, שְׁמַע תְּחִנָּתִי חִישׁ נָא יְשׁוּעָתִי, אַל תַּעְלֵם אָזְנְךָ לְרַוְחָתִי לְשַׁוְעָתִי: יֶרַח טֵבֵת מְאֹד לָקִיתִי בוֹ, וְנִשְׁתַּנּוּ עָלַי סִדְרֵי נְתִיבוֹ, סָרַרְתִּי פָּשַׁעְתִּי יְגַלֶּה לִי טוּבוֹ, הָאוֹמֵר לַיָּם עַד פֹּה תָבֹא.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, מִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לְחַטָּאִים, וּסְלִיחָה לְפוֹשְׁעִים. עֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וָרוּחַ, לֹא כְרָעָתָם תִּגְמֹל. אֵל, הוֹרֵיתָ לָּנוּ לוֹמַר שְׁלֹשׁ עֶשְׂרֵה, וּזְכָר לָנוּ הַיּוֹם בְּרִית שְׁלשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָיו מִקֶּדֶם, כְּמוֹ שֶׁכָּתוּב: וַיֵּרֶד יהוה בֶּעָנָן, וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם, יהוה:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אֱלֹהִים, בָּאוּ גוֹיִם בְּנַחֲלָתֶךָ, טִמְּאוּ אֶת הֵיכַל קָדְשֶׁךָ, שָׂמוּ אֶת יְרוּשָׁלַיִם לְעִיִּים: אֱלֹהִים, זֵדִים קָמוּ עָלֵינוּ, וַעֲדַת עָרִיצִים בִּקְשׁוּ נַפְשֵׁנוּ, וְלֹא שָׂמוּךָ לְנֶגְדָּם:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"כְּרַחֵם אָב עַל בָּנִים, כֵּן תְּרַחֵם יהוה עָלֵינוּ. לַיהוה הַיְּשׁוּעָה, עַל עַמְּךָ בִרְכָתֶךָ סֶּלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶּלָה: יהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֶבֶן הָרֹאשָׁה, לְעִיִּים וְלַחֲרִישָׁה, וְנוֹחֲלֵי מוֹרָשָׁה, מְנוֹד רֹאשׁ בַּלְאֻמִים. בְּקִרְבִּי לֵב נִכְאָב, נִדְוֶה וְנִדְאָב, נִשְׁאַרְנוּ כְּאֵין אָב, וְהָיִינוּ כִּיתוֹמִים. רַכָּה וַעֲנֻגָּה, בַּשּׁוֹשַׁנִּים סוּגָה, וְעַתָּה הִיא נוּגָה, מְסוּרָה בְּיַד קָמִים. הָיְתָה כְּאַלְמָנָה, קִרְיָה נֶאֱמָנָה, וְזֶרַע מִי מָנָה, נִמְכְּרוּ בְּלֹא דָּמִים. מְעֻנָּגָה וְרַכָּה, צָלְחָה לִמְלוּכָה, וּמַעֲנִיתָהּ אָרְכָה, זֶה כַּמֶּה שָׁנִים וְיָמִים. בֵּית יַעֲקֹב לְבִזָּה, לְלַעַג וּלְעִזָּה, הָעִיר הָעַלִּיזָה, לְמַטָּעֵי כְרָמִים. רְווּיָה תַרְעֵלָה, בְּיַד בְּנֵי עַוְלָה, הָרְצוּיָה כְעוֹלָה, וְכִקְטֹרֶת הַסַּמִּים. מָאֲסָה לִזְנֹחַ, תּוֹרַת אֲבִי זָנוֹחַ, וְלֹא מָצְאָה מָנוֹחַ, לֵילוֹת וְגַם יָמִים. נוֹרָא אֵל עֶלְיוֹן, מִמְּךָ יְהִי צִבְיוֹ,. לְהָשִׁיב לְרִיב צִיּוֹן, שְׁנַת שִׁלּוּמִים. חַדֵּשׁ יָמֵינוּ כְּקֶדֶם, מְעוֹנָה אֱלֹהֵי קֶדֶם, וְלַבֵּן כַּצֶּמֶר אֹדֶם, וְכַשֶּׁלֶג כְּתָמִים. חַזְּקֵנוּ בְּיִרְאָתֶךָ, וּבְקִיּוּם תּוֹרָתֶךָ, וּפָקְדֵנוּ בִּישׁוּעָתֶךָ, אֵל מָלֵא רַחֲמִים.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, מִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לְחַטָּאִים, וּסְלִיחָה לְפוֹשְׁעִים. עֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וָרוּחַ, לֹא כְרָעָתָם תִּגְמֹל. אֵל, הוֹרֵיתָ לָּנוּ לוֹמַר שְׁלֹשׁ עֶשְׂרֵה, וּזְכָר לָנוּ הַיּוֹם בְּרִית שְׁלשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָיו מִקֶּדֶם, כְּמוֹ שֶׁכָּתוּב: וַיֵּרֶד יהוה בֶּעָנָן, וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם, יהוה:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"פזמון. שליח הציבור אומר את הבית הראשון, והקהל חוזר אחריו, ולאחר מכן כל בית הקהל אומר ושליח הציבור חוזר.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי, גָּדְלוּ וְהִצְלִיחוּ וְגַם עָשׂוּ פֶרִי, וּמֵעֵת הֻדָּחוּ וְהָלְכוּ עִמּוֹ קֶרִי, הָיוּ הָלוֹךְ וְחָסוֹר עַד הַחֹדֶשׁ הָעֲשִׂירִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"בָּעֲשִׂירִי לַחֹדֶשׁ סָמַךְ מֶלֶךְ בָּבֶל, וְצָר עַל עִיר הַקֹּדֶשׁ וְנִקְרַב רַב הַחוֹבֵל, נֻתַּתִּי הָדֵשׁ וְעֻנֵּיתִי בַכֶּבֶל, וְהָיָה מִדֵּי חֹדֶשׁ לְאֵבֶל כִּנּוֹרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"רֵאשִׁית בִּכּוּרָה לְרֵאשִׁית הַחֵרֶם, שֵׁם אֲחֵרִים הִזְכִּירָה וְהֶעָוׂן גּוֹרֵם, פְּנֵי אֵל לֹא הִכִּירָה וְשֻׁטְּפָה בְזֶרֶם, צָרָה כְּמַבְכִּירָה כָּעֵת בַּמָּרוֹם תַּמְרִיא.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"הָאֱלֹהִים הֵבִיא יוֹם רָעָה וּמָצוֹר, צִוָּה צָרַי סְבִיבִי עוֹלָלַי לִבְצוֹר, יוֹם הֵרַךְ לְבָבִי וְאֵין כֹּחַ לַעֲצֹר, וְדִבֶּר אֶל נָבִיא מְשֹׁל אֶל בֵּית הַמֶּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"מִיּוֹשְׁבֵי שַׁעַר הֶעֱבִיר אַדֶּרֶת, חֲמָתוֹ כָּאֵשׁ בָּעַר וְהֵרִים עֲטֶרֶת, וּמִלְּבָנוֹן יַעַר הִשְׁלִיךְ תִּפְאֶרֶת, וְרוּחַ סוֹעָה וָסַעַר תְּסַמֵּר שַׂעֲרַת בְּשָׂרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"יָפְיָפִית נִמְשַׁלְתְּ וְעַתָּה קְדוֹרַנִּית, בְּעָוׂן כִּי כָשַׁלְתְּ וְלִבֵּךְ אֲחוֹרַנִּית, זִנְּבוּךְ וְנֶחֱשַׁלְתְּ רִאשׁוֹנָה וְשֵׁנִית, וְהָחְתֵּל לֹא חֻתַּלְתְּ מְעַט צֳרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"צַדִּיק הַצּוּר תָּם נְשֹׂא עָוׂן נִלְאָה, מִכְּרוּב לְמִפְתָּן לְפִנַּת גַּג דָּאָה, מֵעָוׂן הַנִּכְתָּם וְצַעֲקָתָם בָּאָה, רַבָּה רָעָתָם כְּעֵץ עֹשֶׂה פֶּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"חִזֵּק כָּל קָמַי תּוֹכֵן הָעֲלִילוֹת, כִּי מָלְאוּ יָמַי בְּרֹעַ מִפְעָלוֹת, וּמִבֹּשֶׁת עֲלוּמַי שָׁכַחְתִּי גְמוּלוֹת, נוֹתֵן לַחְמִי וּמֵימַי פִּשְׁתִּי וְצַמְרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"קָמַי פִּיהֶם פָּעֲרוּ וְנַחֲלָתִי בִּלֵּעוּ, מְאֹד עָלַי גָּבָרוּ וְדָמִי שָׁתוּ וְלָעוּ, נָכְרִים עָלַי צָרוּ וְאֶת אַחַי הֵרֵעוּ, הָאוֹמְרִים עָרוּ עָרוּ בְּנֵי שֵׂעִיר הַחוֹרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אָמְרוּ לְכוּ נְכַלֵּם וְנַשְׁבִּיתָה זִכְרָם, אֵל קַנֹּא וְנוֹקֵם גָּמְלֵם יִשְׂאוּ אֶת שִׁבְרָם, כְּמַעֲשֵׂיהֶם שַׁלֵּם וְיֵבֹשׁוּ מִשִּׂבְרָם, כְּאִישׁ חֲלוֹם חוֹלֵם שְׁלֹשָׁה סַלֵּי חוֹרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"פִּצְעִי לֹא רֻכָּכָה וְחַבּוּרוֹתַי רֶצַח, וְעֵינִי הֻכְהָתָה צוֹפָה לְדוֹדִי צַח, הַעוֹד לֹא שָׁכָכָה חֲמָתוֹ לָנֶצַח, עַל מֶה עָשָׂה כָּכָה וּמֶה חֳרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"רַחוּם זֶה אֵלִי אַל לָעַד תִּזְנַח, אָרְכוּ יְמֵי אֶבְלִי וְעוֹד לִבִּי נֶאֱנַח, שׁוּבָה אֵל לְאָהֳלִי מְקוֹמְךָ אַל תַּנַּח, שַׁלֵּם יְמֵי אֶבְלִי כִּי תָבוֹא עַל שְׂכָרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"יהוה מְנָת חֶלְקִי חוּשָׁה לִּי לְעֶזְרָה, וּפִתַּחְתָּ שַׂקִּי שִׂמְחָה לִי לְאַזְּרָה, וְתַגִּיהַּ אֶת חָשְׁכִּי בְּאוֹרְךָ לְהָאִירָה, אֶת נֶשֶׁף חִשְׁקִי כִּי אַתָּה נֵרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"מִיָּגוֹן וַאֲנָחָה פְּדֵה אֵל אֶת נַפְשִׁי, עֲשֵׂה לְעַמְּךָ הֲנָחָה מַלְכִּי וּקְדוֹשִׁי, תַּהֲפוֹךְ לִרְוָחָה אֶת צוֹם הַחֲמִישִׁי, לְשָׂשׂוֹן וּלְשִׂמְחָה צוֹם הָרְבִיעִי וְצוֹם הָעֲשִׂירִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אֲבוֹתַי כִּי בָטְחוּ בְּשֵׁם אֱלֹהֵי צוּרִי.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, מִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לְחַטָּאִים, וּסְלִיחָה לְפוֹשְׁעִים. עֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וָרוּחַ, לֹא כְרָעָתָם תִּגְמֹל. אֵל, הוֹרֵיתָ לָּנוּ לוֹמַר שְׁלֹשׁ עֶשְׂרֵה, וּזְכָר לָנוּ הַיּוֹם בְּרִית שְׁלשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָיו מִקֶּדֶם, כְּמוֹ שֶׁכָּתוּב: וַיֵּרֶד יהוה בֶּעָנָן, וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם, יהוה:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"זְכֹר רַחֲמֶיךָ יהוה וַחֲסָדֶיךָ, כִּי מֵעוֹלָם הֵמָּה: זָכְרֵנוּ יהוה בִּרְצוֹן עַמֶּךָ, פָּקְדֵנוּ בִּישׁוּעָתֶךָ. זְכֹר עֲדָתְךָ קָנִיתָ קֶדֶם, גָּאַלְתָּ שֵׁבֶט נַחֲלָתֶךָ, הַר צִיּוֹן זֶה שָׁכַנְתָּ בּוֹ: זְכֹר יהוה חִבַּת יְרוּשָׁלָיִם, אַהֲבַת צִיּוֹן אַל תִּשְׁכַּח לָנֶצַח. אַתָּה תָקוּם תְּרַחֵם צִיּוֹן, כִּי עֵת לְחֶנְנָהּ, כִּי בָא מוֹעֵד: זְכֹר יהוה לִבְנֵי אֱדוֹם אֵת יוֹם יְרוּשָׁלָיִם, הָאוֹמְרִים עָרוּ עָרוּ, עַד הַיְסוֹד בָּהּ: זְכֹר לְאַבְרָהָם לְיִצְחָק וּלְיִשְׂרָאֵל עֲבָדֶיךָ, אֲשֶׁר נִשְׁבַּעְתָּ לָהֶם בָּךְ, וַתְּדַבֵּר אֲלֵהֶם, אַרְבֶּה אֶת זַרְעֲכֶם כְּכוֹכְבֵי הַשָּׁמַיִם, וְכָל הָאָרֶץ הַזֹּאת אֲשֶׁר אָמַרְתִּי אֶתֵּן לְזַרְעֲכֶם, וְנָחֲלוּ לְעוֹלָם: זְכֹר לַעֲבָדֶיךָ לְאַבְרָהָם לְיִצְחָק וּלְיַעֲקֹב, אַל תֵּפֶן אֶל קְשִׁי הָעָם הַזֶּה וְאֶל רִשְׁעוֹ וְאֶל חַטָּאתוֹ:\n\nאַל נָא תָשֵׁת עָלֵינוּ חַטָּאת אֲשֶׁר נוֹאַלְנוּ וַאֲשֶׁר חָטָאנוּ: חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"יש המוסיפים פיוט זה ואומרים אותו בית בית עם שליח הציבור:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אֵל נָא, רְפָא נָא תַּחֲלוּאֵי גֶפֶן פּוֹרִיָּה, בּוֹשָׁה וַחֲפוּרָה וְאֻמְלַל פִּרְיָהּ, גְּאָלֶנָּה מִשַּׁחַת וּמִמַּכָּה טְרִיָּה, עֲנֵנוּ כְּשֶׁעָנִיתָ לְאַבְרָהָם אָבִינוּ בְּהַר הַמּוֹרִיָּה.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"דִּגְלֵי עָם פְּדוּיֵי בִּזְרוֹעַ חָשׂוּף, הַצֵּל מִנֶּגֶף וְאַל יִהְיוּ לְשִׁסּוּף, וְתַעֲנֶה קְרִיאָתֵנוּ וּלְמַעֲשֵׂה יָדֶיךָ תִּכְסֹף, עֲנֵנוּ כְּשֶׁעָנִיתָ לַאֲבוֹתֵינוּ עַל יַם סוּף.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"זְכוּת צוּר חֻצַּב הַיּוֹם לָנוּ תְגַל, חָשְׂכֵנוּ מֵאֶנֶף וּנְחֵנוּ בְּיֹשֶׁר מַעְגָּל, טַהֵר טֻמְאָתֵנוּ וְלִמְאוֹר תּוֹרָתְךָ עֵינֵינוּ גַל, עֲנֵנוּ כְּשֶׁעָנִיתָ לִיהוֹשֻׁעַ בַּגִּלְגָּל.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"יָהּ, רְאֵה דֶשֶׁן עָקוּד וְהַצְמַח לָנוּ תְרוּפָה, כַּלֵּה שׁוֹד וָשֶׁבֶר, סַעַר וְסוּפָה, לַמְּדֵנוּ וְחַכְּמֵנוּ אִמְרָתְךָ הַצְּרוּפָה, עֲנֵנוּ כְּשֶׁעָנִיתָ לִשְׁמוּאֵל בַּמִּצְפָּה.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"מֻתְמָם מֵרֶחֶם שָׁרָשָׁיו אַל תַּקְמֵל, נַקֵּנוּ מִכֶּתֶם וְשֶׁמֶץ וְלֹא נֵאָמֵל, סְעָדֵנוּ וְנִוָּשֵׁעָה וְאָרְחוֹת חֲסָדֶיךָ נִגָּמֵל, עֲנֵנוּ כְּשֶׁעָנִיתָ לְאֵלִיָּהוּ בְּהַר הַכַּרְמֶל.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"עוֹדְדֵנוּ בְּצֶדֶק מָשׁוּי מִמַּיִם וְכַפֵּר זָדוֹן וּמְשׁוּגָה, פְּדֵנוּ מִמְּהוּמַת מָוֶת וְאָחוֹר בַּל נִסּוֹגָה, צַוֵּה יְשׁוּעָתֵנוּ וּבַעֲוׂנוֹתֵינוּ אַל נִתְמוֹגְגָה, עֲנֵנוּ כְּשֶׁעָנִיתָ לְיוֹנָה בִּמְעֵי הַדָּגָה.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"קְדֻשַּׁת אִישׁ חֲסִידֶךָ זְכֹר לִיפַת פַּעֲמַיִם, רַחֲמֶיךָ תְּעוֹרֵר כִּי לָקִינוּ בְּכִפְלַיִם, שׁוּבֵנוּ תֹּקֶף לְיִרְאָתֶךָ וְלֹא נֵחָשֵׂף שׁוּלַיִם, עֲנֵנוּ כְּשֶׁעָנִיתָ לְדָוִד וְלִשְׁלֹמֹה בְנוֹ בִּירוּשָׁלַיִם.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"בתענית אסתר יש מוסיפים:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"תַּעֲנֶה לְקוֹרְאֶיךָ וְהַסְכֵּת מִמְּעוֹנִים, תִּשְׁמַע שַׁוְעַת צוֹעֲקֶיךָ, שׁוֹמֵעַ אֶל אֶבְיוֹנִים, תְּרַחֵם עַל בָּנֶיךָ כְּרַחֵם אָב עַל בָּנִים, עֲנֵנוּ כְּמוֹ שֶׁעָנִיתָ לְמָרְדְּכַי וְאֶסְתֵּר, וְתָלוּ עַל עֵץ חֲמִשִּׁים הָאָב עִם הַבָּנִים.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"מכאן כולם אומרים:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"זְכֹר לָנוּ בְּרִית אָבוֹת כַּאֲשֶׁר אָמַרְתָּ: וְזָכַרְתִּי אֶת בְּרִיתִי יַעֲקוֹב וְאַף אֶת בְּרִיתִי יִצְחָק וְאַף אֶת בְּרִיתִי אַבְרָהָם אֶזְכֹּר, וְהָאָרֶץ אֶזְכֹּר:\n\nזְכֹר לָנוּ בְּרִית רִאשׁוֹנִים כַּאֲשֶׁר אָמַרְתָּ: וְזָכַרְתִּי לָהֶם בְּרִית רִאשׁוֹנִים אֲשֶׁר הוֹצֵאתִי אוֹתָם מֵאֶרֶץ מִצְרַיִם לְעֵינֵי הַגּוֹיִם לִהְיוֹת לָהֶם לֵאלֹהִים, אֲנִי יהוה:\n\nעֲשֵׂה עִמָּנוּ כְּמָה שֶׁהִבְטַחְתָּנוּ: וְאַף גַּם זֹאת בִּהְיוֹתָם בְּאֶרֶץ אוֹיְבֵיהֶם לֹא מְאַסְתִּים וְלֹא גְעַלְתִּים לְכַלּוֹתָם לְהָפֵר בְּרִיתִי אִתָּם, כִּי אֲנִי יהוה אֱלֹהֵיהֶם: הָשֵׁב שְׁבוּתֵנוּ וְרַחֲמֵנוּ כְּמָה שֶׁכָּתוּב: וְשָׁב יהוה אֱלֹהֶיךָ אֶת שְׁבוּתְךָ וְרִחֲמֶךָ, וְשָׁב וְקִבֶּצְךָ מִכָּל הָעַמִּים אֲשֶׁר הֱפִיצְךָ יהוה אֱלֹהֶיךָ שָׁמָּה: קַבֵּץ נִדָּחֵינוּ כְּמָה שֶׁכָּתוּב: אִם יִהְיֶה נִדַּחֲךָ בִּקְצֵה הַשָּׁמָיִם, מִשָּׁם יְקַבֶּצְךָ יהוה אֱלֹהֶיךָ וּמִשָּׁם יִקָּחֶךָ: מְחֵה פְשָׁעֵינוּ כָּעָב וְכֶעָנָן כְּמָה שֶׁכָּתוּב: מָחִיתִי כָעָב פְּשָׁעֶיךָ וְכֶעָנָן חַטֹּאתֶיךָ, שׁוּבָה אֵלַי כִּי גְאַלְתִּיךָ: מְחֵה פְשָׁעֵינוּ לְמַעַנְךָ כַּאֲשֶׁר אָמַרְתָּ: אָנֹכִי אָנֹכִי הוּא מֹחֶה פְשָׁעֶיךָ לְמַעֲנִי, וְחַטֹּאתֶיךָ לֹא אֶזְכֹּר: הַלְבֵּן חֲטָאֵינוּ כַּשֶּׁלֶג וְכַצֶּמֶר כְּמָה שֶׁכָּתוּב: לְכוּ נָא וְנִוָּכְחָה יֹאמַר יהוה, אִם יִהְיוּ חֲטָאֵיכֶם כַּשָּׁנִים כַּשֶּׁלֶג יַלְבִּינוּ, אִם יַאְדִּימוּ כַתּוֹלָע כַּצֶּמֶר יִהְיוּ: זְרֹק עָלֵינוּ מַיִם טְהוֹרִים וְטַהֲרֵנוּ כְּמָה שֶׁכָּתוּב: וְזָרַקְתִּי עֲלֵיכֶם מַיִם טְהוֹרִים וּטְהַרְתֶּם, מִכֹּל טֻמְאֹתֵיכֶם וּמִכָּל גִּלּוּלֵיכֶם אֲטַהֵר אֶתְכֶם: רַחֵם עָלֵינוּ וְאַל תַּשְׁחִיתֵנוּ כְּמָה שֶׁכָּתוּב: כִּי אֵל רַחוּם יהוה אֱלֹהֶיךָ, לֹא יַרְפְּךָ וְלֹא יַשְׁחִיתֶךָ, וְלֹא יִשְׁכַּח אֶת בְּרִית אֲבֹתֶיךָ אֲשֶׁר נִשְׁבַּע לָהֶם: מוֹל אֶת לְבָבֵנוּ לְאַהֲבָה אֶת שְׁמֶךָ כְּמָה שֶׁכָּתוּב: וּמָל יהוה אֱלֹהֶיךָ אֶת לְבָבְךָ וְאֶת לְבַב זַרְעֶךָ, לְאַהֲבָה אֶת יהוה אֱלֹהֶיךָ בְּכָל לְבָבְךָ וּבְכָל נַפְשְׁךָ, לְמַעַן חַיֶּיךָ: הִמָּצֵא לָנוּ בְּבַקָּשָׁתֵנוּ כְּמָה שֶׁכָּתוּב: וּבִקַּשְׁתֶּם מִשָּׁם אֶת יהוה אֱלֹהֶיךָ וּמָצָאתָ, כִּי תִדְרְשֶׁנּוּ בְּכָל לְבָבְךָ וּבְכָל נַפְשֶׁךָ: תְּבִיאֵנוּ אֶל הַר קָדְשֶׁךָ וְשַׂמְּחֵנוּ בְּבֵית תְּפִלָּתֶךָ כְּמָה שֶׁכָּתוּב: וַהֲבִיאוֹתִים אֶל הַר קָדְשִׁי וְשִׂמַּחְתִּים בְּבֵית תְּפִלָּתִי, עוֹלוֹתֵיהֶם וְזִבְחֵיהֶם לְרָצוֹן עַל מִזְבְּחִי, כִּי בֵיתִי, בֵּית תְּפִלָּה יִקָּרֵא לְכָל הָעַמִּים:","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"פותחים את ארון הקודש ואמורים משפט משפט. יש קהילות בהם סדר המשפטים שונה וברוב הקהילות מדלגים על המשפט \"יהיו לרצון\".","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"שְׁמַע קוֹלֵנוּ, יהוה אֱלֹהֵינוּ, חוּס וְרַחֵם עָלֵינוּ, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ. הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם: אֲמָרֵינוּ הַאֲזִינָה יהוה, בִּינָה הֲגִיגֵנוּ. יִהְיוּ לְרָצוֹן אִמְרֵי פִינוּ וְהֶגְיוֹן לִבֵּנוּ לְפָנֶיךָ, יהוה צוּרֵנוּ וְגוֹאֲלֵנוּ. אַל תַּשְׁלִיכֵנוּ מִלְּפָנֶיךָ, וְרוּחַ קָדְשְׁךָ אַל תִּקַּח מִמֶּנּוּ. אַל תַּשְׁלִיכֵנוּ לְעֵת זִקְנָה, כִּכְלוֹת כֹּחֵנוּ אַל תַּעַזְבֵנוּ.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"מכאן מפסיקים לומר עם החזן בקול.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אַל תַּעַזְבֵנוּ יהוה, אֱלֹהֵינוּ אַל תִּרְחַק מִמֶּנוּ. עֲשֵׂה עִמָּנוּ אוֹת לְטוֹבָה, וְיִרְאוּ שׂוֹנְאֵינוּ וְיֵבוֹשׁוּ, כִּי אַתָּה יהוה עֲזַרְתָּנוּ וְנִחַמְתָּנוּ. כִּי לְךָ יהוה הוֹחָלְנוּ, אַתָּה תַעֲנֶה אֲדֹנָי אֱלֹהֵינוּ.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"סוגרים את ארון הקודש.","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, תָּבוֹא לְפָנֶיךָ תְּפִלָּתֵנוּ וְאַל תִּתְעַלַּם מִתְּחִנָּתֵנוּ, שֶׁאֵין אָנוּ עַזֵּי פָנִים וּקְשֵׁי עֹרֶף לוֹמַר לְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ צַדִּיקִים אֲנַחְנוּ וְלֹא חָטָאנוּ, אֲבָל אֲנַחְנוּ וַאֲבוֹתֵינוּ חָטָאנוּ.\nאָשַׁמְנוּ, בָּגַדְנוּ, גָּזַלְנוּ, דִּבַּרְנוּ דֹפִי. הֶעֱוִינוּ, וְהִרְשַׁענוּ, זַדְנוּ, חָמַסְנוּ, טָפַלְנוּ שֶׁקֶר. יָעַצְנוּ רָע, כְּזַּבְנוּ, לַצְנוּ, מָרַדְנוּ, נִאַצְנוּ, סָרַרְנוּ, עָוְינוּ, פָּשַׁעְנוּ, צָרַרְנוּ, קִשִּׁינוּ עֹרֶף. רָשַׁעְנוּ, שִׁחַתְנוּ, תִּעַבְנוּ, תָּעִינוּ, תִּעְתַּעְנוּ.\nסַרְנוּ מִמִּצְוׂתֶיךָ וּמִמִּשְׁפָּטֶיךָ הַטּוֹבִים וְלֹא שָׁוָה-לָנוּ. וְאַתָּה צַדִּיק עַל כָּל הַבָּא עָלֵינוּ, כִּי אֱמֶת עָשִׂיתָ, וַאֲנַחְנוּ הִרְשָׁעְנוּ:\n\nהִרְשַׁעְנוּ וּפָשַׁעְנוּ לָכֵן לֹא נוֹשָׁעְנוּ. וְתֵן בְּלִבֵּנוּ לַעֲזֹב דֶּרֶךְ רֶשַׁע, וְחִישׁ לָנוּ יֶשַׁע, כַּכָּתוּב עַל יַד נְבִיאֶךָ: יַעֲזוֹב רָשָׁע דַּרְכּוֹ וְאִישׁ אָוֶן מַחְשְׁבֹתָיו, וְיָשֹׁב אֶל יהוה וִירַחֲמֵהוּ, וְאֶל אֱלֹהֵינוּ כִּי יַרְבֶּה לִסְלוֹחַ:\n\nמְשִׁיחַ צִדְקֶךָ אָמַר לְפָנֶיךָ: שְׁגִיאוֹת מִי יָבִין מִנִּסְתָּרוֹת נַקֵּנִי: נַקֵּנוּ יהוה אֱלֹהֵינוּ מִכָּל פְּשָׁעֵינוּ וְטַהֲרֵנוּ מִכָּל טֻמְאוֹתֵינוּ, וּזְרֹק עָלֵינוּ מַיִם טְהוֹרִים וְטַהֲרֵנוּ, כַּכָּתוּב עַל יַד נְבִיאֶךָ: וְזָרַקְתִּי עֲלֵיכֶם מַיִם טְהוֹרִים וּטְהַרְתֶּם, מִכֹּל טֻמְאוֹתֵיכֶם וּמִכָּל גִּלּוּלֵיכֶם אֲטַהֵר אֶתְכֶם: עַמְּךָ וְנַחֲלָתְךָ רְעֵבֵי טוּבְךָ, צְמֵאֵי חַסְדְּךָ, תְּאֵבֵי יִשְׁעֶךָ. יַכִּירוּ וְיֵדְעוּ כִּי לַיהוה אֱלֹהֵינוּ הָרַחֲמִים וְהַסְּלִיחוֹת.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"אם אין אומרים תחנון מדלגים על המשך הסליחות.","cond":["shacharitTachanun","10tevet","shacharitTachanun"]},{"kind":"text","text":"אֵל רַחוּם שְׁמֶךָ. אֵל חַנּוּן שְׁמֶךָ. בָּנוּ נִקְרָא שְׁמֶךָ. יהוה עֲשֵׂה לְמַעַן שְׁמֶךָ. עֲשֵׂה לְמַעַן אֲמִתָּךְ. עֲשֵׂה לְמַעַן בְּרִיתָךְ. עֲשֵׂה לְמַעַן גָּדְלָךְ וְתִפְאַרְתָּךְ. עֲשֵׂה לְמַעַן דָּתָךְ. עֲשֵׂה לְמַעַן הוֹדָךְ. עֲשֵׂה לְמַעַן וִעוּדָךְ. עֲשֵׂה לְמַעַן זִכְרָךְ. עֲשֵׂה לְמַעַן חַסְדָּךְ. עֲשֵׂה לְמַעַן טוּבָךְ. עֲשֵׂה לְמַעַן יִחוּדָךְ. עֲשֵׂה לְמַעַן כְּבוֹדָךְ. עֲשֵׂה לְמַעַן לִמּוּדָךְ. עֲשֵׂה לְמַעַן מַלְכוּתָךְ. עֲשֵׂה לְמַעַן נִצְחָךְ. עֲשֵׂה לְמַעַן סוֹדָךְ. עֲשֵׂה לְמַעַן עֻזָּךְ. עֲשֵׂה לְמַעַן פְּאֵרָךְ. עֲשֵׂה לְמַעַן צִדְקָתָךְ. עֲשֵׂה לְמַעַן קְדֻשָׁתָךְ. עֲשֵׂה לְמַעַן רַחֲמֶיךָ הָרַבִּים. עֲשֵׂה לְמַעַן שְׁכִינָתָךְ. עֲשֵׂה לְמַעַן תְּהִלָּתָךְ. עֲשֵׂה לְמַעַן אוֹהֲבֶיךָ שׁוֹכְנֵי עָפָר. עֲשֵׂה לְמַעַן אַבְרָהָם יִצְחָק וְיַעֲקֹב. עֲשֵׂה לְמַעַן מֹשֶׁה וְאַהֲרֹן. עֲשֵׂה לְמַעַן דָּוִד וּשְׁלֹמֹה. עֲשֵׂה לְמַעַן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ. עֲשֵׂה לְמַעַן צִיּוֹן מִשְׁכַּן כְּבוֹדֶךָ. עֲשֵׂה לְמַעַן שִׁמְמוֹת הֵיכָלֶךָ. עֲשֵׂה לְמַעַן הֲרִיסוּת מִזְבְּחֶךָ. עֲשֵׂה לְמַעַן הֲרוּגִים עַל שֵׁם קָדְשֶׁךָ. עֲשֵׂה לְמַעַן טְבוּחִים עַל יִחוּדֶךָ. עֲשֵׂה לְמַעַן בָּאֵי בָאֵשׁ וּבַמַּיִם עַל קִדּוּשׁ שְׁמֶךָ. עֲשֵׂה לְמַעַן יוֹנְקֵי שָׁדַיִם שֶׁלֹּא חָטְאוּ. עֲשֵׂה לְמַעַן גְּמוּלֵי חָלָב שֶׁלֹּא פָשְׁעוּ. עֲשֵׂה לְמַעַן תִּינוֹקוֹת שֶׁל בֵּית רַבָּן. עֲשֵׂה לְמַעַנְךָ אִם לֹא לְמַעֲנֵנוּ. עֲשֵׂה לְמַעַנְךָ וְהוֹשִׁיעֵנוּ.\n\nעֲנֵנוּ יהוה עֲנֵנוּ. עֲנֵנוּ אֱלֹהֵינוּ עֲנֵנוּ. עֲנֵנוּ אָבִינוּ עֲנֵנוּ. עֲנֵנוּ בּוֹרְאֵנוּ עֲנֵנוּ. עֲנֵנוּ גּוֹאֲלֵנוּ עֲנֵנוּ. עֲנֵנוּ דּוֹרְשֵׁנוּ עֲנֵנוּ. עֲנֵנוּ הָאֵל הַנֶּאֱמָן עֲנֵנוּ. עֲנֵנוּ וָתִיק וְחָסִיד עֲנֵנוּ. עֲנֵנוּ זַךְ וְיָשָׁר עֲנֵנוּ. עֲנֵנוּ חַי וְקַיָּם עֲנֵנוּ. עֲנֵנוּ טוֹב וּמֵטִיב עֲנֵנוּ. עֲנֵנוּ יוֹדֵעַ יֶצֶר עֲנֵנוּ. עֲנֵנוּ כּוֹבֵשׁ כְּעָסִים עֲנֵנוּ. עֲנֵנוּ לוֹבֵשׁ צְדָקוֹת עֲנֵנוּ. עֲנֵנוּ מֶלֶךְ מַלְכֵי הַמְּלָכִים עֲנֵנוּ. עֲנֵנוּ נוֹרָא וְנִשְׂגָּב עֲנֵנוּ. עֲנֵנוּ סוֹלֵחַ וּמוֹחֵל עֲנֵנוּ. עֲנֵנוּ עוֹנֶה בְּעֵת צָרָה עֲנֵנוּ. עֲנֵנוּ פּוֹדֶה וּמַצִּיל עֲנֵנוּ. עֲנֵנוּ צַדִּיק וְיָשָׁר עֲנֵנוּ. עֲנֵנוּ קָרוֹב לְקוֹרְאָיו עֲנֵנוּ. עֲנֵנוּ רַחוּם וְחַנוּן עֲנֵנוּ. עֲנֵנוּ שׁוֹמֵעַ אֶל אֶבְיוֹנִים עֲנֵנוּ. עֲנֵנוּ תּוֹמֵךְ תְּמִימִים עֲנֵנוּ. עֲנֵנוּ אֱלֹהֵי אֲבוֹתֵינוּ עֲנֵנוּ. עֲנֵנוּ אֱלֹהֵי אַבְרָהָם עֲנֵנוּ. עֲנֵנוּ פַּחַד יִצְחָק עֲנֵנוּ. עֲנֵנוּ אֲבִיר יַעֲקֹב עֲנֵנוּ. עֲנֵנוּ עֶזְרַת הַשְּׁבָטִים עֲנֵנוּ. עֲנֵנוּ מִשְׂגַּב אִמָּהוֹת עֲנֵנוּ. עֲנֵנוּ קָשֶׁה לִכְעוֹס עֲנֵנוּ. עֲנֵנוּ רַךְ לִרְצוֹת עֲנֵנוּ. עֲנֵנוּ עוֹנֶה בְּעֵת רָצוֹן עֲנֵנוּ. עֲנֵנוּ אֲבִי יְתוֹמִים עֲנֵנוּ. עֲנֵנוּ דַּיַּן אַלְמָנוֹת עֲנֵנוּ.\n\nמִי שֶׁעָנָה לְאַבְרָהָם אָבִינוּ בְּהַר הַמּוֹרִיָּה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְיִצְחָק בְּנוֹ כְּשֶׁנֶּעֱקַד עַל גַּבֵּי הַמִּזְבֵּחַ הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְיַעֲקֹב בְּבֵית אֵל הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְיוֹסֵף בְּבֵית הָאֲסוּרִים הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לַאֲבוֹתֵינוּ עַל יַם סוּף הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְמֹשֶׁה בְּחוֹרֵב הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְאַהֲרֹן בַּמַּחְתָּה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְפִינְחָס בְּקוּמוֹ מִתּוֹךְ הָעֵדָה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לִיהוֹשֻׁעַ בַּגִּלְגָּל הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לִשְׁמוּאֵל בַּמִּצְפָּה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְדָוִד וּשְׁלֹמֹה בְנוֹ בִּירוּשָׁלָיִם הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְאֵלִיָּהוּ בְּהַר הַכַּרְמֶל הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לֶאֱלִישָׁע בִּירִיחוֹ הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְיוֹנָה בִּמְעֵי הַדָּגָה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְחִזְקִיָּהוּ מֶלֶךְ יְהוּדָה בְּחָלְיוֹ הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לַחֲנַנְיָה מִישָׁאֵל וַעֲזַרְיָה בְּתוֹךְ כִּבְשַׁן הָאֵשׁ הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְדָנִיֵּאל בְּגוֹב הָאֲרָיוֹת הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְמָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְעֶזְרָא בַּגּוֹלָה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְכָל הַצַּדִּיקִים וְהַחֲסִידִים וְהַתְּמִימִים וְהַיְּשָׁרִים הוּא יַעֲנֵנוּ.\n\nרַחֲמָנָא דְעָנֵי לַעֲנִיֵי עֲנֵינָא. רַחֲמָנָא דְעָנֵי לִתְבִירֵי לִבָּא עֲנֵינָן. רַחֲמָנָא דְעָנֵי לְמַכִּיכֵי רוּחָא עֲנֵינָן. רַחֲמָנָא עֲנֵינָן. רַחֲמָנָא חוּס. רַחֲמָנָא פְּרוֹק. רַחֲמָנָא שְׁזִיב. רַחֲמָנָא רְחַם עֲלָן. הַשְׁתָּא בַּעֲגָלָא וּבִזְמַן קָרִיב.","cond":["shacharitTachanun","10tevet","shacharitTachanun"]},{"kind":"header","text":"סליחות לתענית אסתר","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"סליחות לתענית אסתר","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"סְלַח לָנוּ אָבִינוּ כִּי בְּרֹב אִוַּלְתֵּנוּ שָׁגִינוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי רַבּוּ עֲוׂנֵינוּ.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"אֵל אֶרֶךְ אַפַּיִם אַתָּה וּבַעַל הָרַחֲמִים נִקְרֵאתָ, וְדֶרֶךְ תְּשׁוּבָה הוֹרֵיתָ, גְּדֻלַּת רַחֲמֶיךָ וַחֲסָדֶיךָ תִּזְכֹּר הַיּוֹם וּבְכָל יוֹם לְזֶרַע יְדִידֶיךָ. תֵּפֶן אֵלֵינוּ בְּרַחֲמִים, כִּי אַתָּה הוּא בַּעַל הָרַחֲמִים. בְּתַחֲנוּן וּבִתְפִלָּה פָּנֶיךָ נְקַדֵּם, כְּהוֹדַעתָּ לֶעָנָו מִקֶּדֶם. מֵחֲרוֹן אַפְּךָ שׁוּב, כְּמוֹ בְּתוֹרָתְךָ כָּתוּב. וּבְצֵל כְּנָפֶיךָ נֶחְסֶה וְנִתְלוֹנָן, כְּיוֹם וַיֵּרֶד יהוה בֶּעָנָן. תַּעֲבֹר עַל פֶּשַׁע וְתִמְחֶה אָשָׁם, כְּיוֹם וַיִּתְיַצֵּב עִמּוֹ שָׁם. תַּאֲזִין שַׁוְעָתֵנוּ וְתַקְשִׁיב מֶנּוּ מַאֲמָר, כְּיוֹם וַיִּקְרָא בְשֵׁם יהוה, וְשָׁם נֶאֲמַר:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"קַוּׂה קִוִּינוּ יהוה, וַיֵּט אֵלֵינוּ וַיּשְׁמַע שַׁוְעָתֵנוּ. אַף אֹרַח מִשְׁפָּטֶיךָ יהוה קִוִּינוּךָ, לְשִׁמְךָ וּלְזִכְרְךָ תַּאֲוַת נָפֶשׁ:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"כְּרַחֵם אָב עַל בָּנִים, כֵּן תְּרַחֵם יהוה עָלֵינוּ. לַיהוה הַיְּשׁוּעָה, עַל עַמְּךָ בִרְכָתֶךָ סֶּלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶּלָה: יהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"סְלַח נָא לַעֲוׂן הָעָם הַזֶּה כְּגֹדֶל חַסְדֶּךָ, וְכַאֲשֶׁר נָשָׂאתָה לָעָם הַזֶּה מִמִּצְרַיִם וְעַד הֵנָּה: וְשָׁם נֶאֱמַר:","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"קהל ואחריו שליח הציבור:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"וַיֹּאמֶר יהוה: סָלַחְתִּי כִּדְבָרֶךָ:\n\nהַטֵּה אֱלֹהַי אָזְנְךָ וּשֲׁמָע, פְּקַח עֵינֶיךָ וּרְאֵה שׁוֹמְמוֹתֵינוּ וְהָעִיר אֲשֶׁר נִקְרָא שִׁמְךָ עָלֶיהָ, כִּי לֹא עַל צִדְקוֹתֵינוּ אֲנַחְנוּ מַפִּילִים תַּחֲנוּנֵינוּ לְפָנֶיךָ, כִּי עַל רַחֲמֶיךָ הָרַבִּים: אֲדֹנָי שְׁמָעָה, אֲדֹנָי סְלָחָה, אֲדֹנָי הַקְשִׁיבָה וַעֲשֵׂה אַל תְּאַחַר, לְמַעַנְךָ אֱלֹהַי, כִּי שִׁמְךָ נִקְרָא עַל עִירְךָ וְעַל עַמֶּךָ:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אָדָם בְּקוּם עָלֵינוּ, חִיל אֲחָזַתְנוּ לִרְעֹד. בְּהִסְתַּפְּחוֹ לְמַלְכוּת חָנֵף, כִּמְעַט כָּשַׁלְנוּ לִמְעֹד. גָּמְרוּ לְמָכְרֵנוּ כְּתֵל וְחָרִיץ בְּלִי מִסְעוֹד, אָמְרוּ: לְכוּ וְנַכְחִידֵם מִגּוֹי וְלֹא יִזָּכֵר שֵׁם יִשְׂרָאֵל עוֹד: דַּלּוּ עֵינַי לַמָּרוֹם, קְרָאתִיךָ אוֹיְבַי לָקֹב. הַכְרֵת שֵׁם וּשְׁאָר, וּמְחֵה שֵׁם לִרְקֹב. וְצֹר צוֹרְרַי בְּנִכְלֵיהֶם אֲשֶׁר נִכְּלוּ לַעֲקֹב. וַיֹּאמְרוּ: לֹא יִרְאֶה יָהּ, וְלֹא יָבִין אֱלֹהֵי יַעֲקֹב: זְרוּיִים עִנָּה וַיַּגֶּה, וְלֹא מִלֵּב לְכַלּוֹתָם. חָבוּ לְפָנִים, וְרִדָּם בַּהֲסָרַת טַבַּעַת לְהַחֲלוֹתָם. טוֹב דְּבָרוֹ הֵקִים לְעֵינֵי הַגּוֹיִם לְהַעֲלוֹתָם. בְּאֶרֶץ אוֹיְבֵיהֶם לֹא מְאַסְתִּים וְלֹא גְעַלְתִּים לְכַלֹּתָם: יִדַּע רֶמֶז הַקּוֹרוֹת לְעַם מְעֻפָּר וּמְהֻדָּס. כְּתָב הַסְתֵּר אַסְתִּיר וּמָר דְּרוֹר מְפֻרְדָּס. לִשְׁבֹּת הָמָן מִמָּחֳרָת, הֲמִן הָעֵץ קֻנְדָּס. תַּחַת הַנַּעֲצוּץ יַעֲלֶה בְרוֹשׁ, וְתַחַת הַסִּרְפָּד יַעֲלֶה הֲדַס: מַקְשִׁיב דְּבַר שֶׁקֶר כָּתַב שִׂטְנָה וָעֶצֶב. נִתְעַטֵּף בְּבִגְדֵי שְׂרָד כְּטָעָה בְּמִנְיַן קֶצֶב. סָדַּר לְהִשְׁתַּמֵּשׁ בְּשׁוֹנִים כְּלֵי הַמַּחֲצֵב. וַיָּבוֹא גַם הַשָּׂטָן בְּתֹכָם לְהִתְיַצֵּב: עַם הַנִּמְצְאִים בְּשׁוּשָׁן, בְּאָכְלָם מִזֶּבַח עוֹכְרָם. פָּעַר פִּיו לְהַשְׂטִינָם, וּלְהַסְגִּירָם בְּיַד נוֹתֵן מִכְרָם. צוּר הִסְכִּים לִכְתֹּב אִגֶּרֶת לְאַבֵּד שִׂבְרָם. אָמַרְתִּי אַפְאֵיהֶם, אַשְׁבִּיתָה מֵאֱנוֹשׁ זִכְרָם: קְדוֹשִׁים מַלְאֲכֵי שָׁלוֹם מַר יִבְכָּיוּן בִּצְעָקָה. רַחוּם הַבֵּט לַבְּרִית וְאַל תָּפֵר לְהַרְחִיקָה. שָׁמְעָה מוֹרָשָׁה, וַתִּלְבַּשׁ בִּגְדֵי אַלְמְנוּת וּמוּעָקָה. וַתָּשֶׂם יָדָהּ עַל רֹאשָׁהּ, וַתֵּלֶךְ הָלוֹךְ וּזְעָקָה: תִּשְׁבִּי שָׂם אֵזוֹר שַׂק בְּמָתְנָיו תַּחְבֹּשֶׁת. מִהֵר וְהוֹדִיעַ יְשֵׁנֵי מַכְפֵּל, אָבוֹת שְׁלֹשֶׁת. נָחַץ לְרוֹעֶה, מַה לְּךָ נִרְדָּם לְהִתְעַשֵּׁת. קוּם קְרָא אֶל אֱלֹהֶיךָ אוּלַי יִתְעַשֵּׁת: חוֹתַם טִיט אֲשֶׁר נַעֲשָׂה, לְבִלְשָׁן סִפֵּר. מִנִּינְוֵה לָמְדוּ לְאַחַר גְּזֵרָה כַּעַס לְהָפֵר. בֶּן קִישׁ הִקִּישׁ דַּלְתוֹת בֵּית הַסֵּפֶר. וַיְּכַס שַׂק, וַיֵּשֶׁב עַל הָאֵפֶר: רִבֵּץ תִּינוֹקוֹת לְפָנָיו יָמִים שְׁלֹשָׁה, צָמִים וּמֻכְפָּנִים. בְּקוֹל יַעֲקֹב לַחֲלֹשׁ יְדֵי עַז פָּנִים. יָדָיו אֱמוּנָה לָאֵל, הַצִּילֵנִי נָא מֵעֶלְבּוֹנִים. פֶּן יָבוֹא וְהִכַּנִי אֵם עַל בָּנִים: מִזֶּה אֵלֶּה וּמִזֶּה אֵלֶּה, בְּנֵי אֵיתָנַי וְרַבָּנָי. כֻּלָּם צָעֲקוּ, וַתַּעַל שַׁוְעָתָם אֶל יהוה. יָהּ, לְקוֹל רִנּוּן כְּבוֹא, שָׁאַל לִפְנָי. וּמֶה קוֹל הַצֹּאן הַזֶּה בְּאָזְנָי: רוֹעֶה הֱשִׁיבוֹ, הֵם קְטַנֵּי קֹדֶשׁ זֶרַע. יָהּ, הַצֵּל לְקוּחִים לַמָּוֶת מֵאוֹיֵב הָרָע. חַנּוּן נִכְמְרוּ רַחֲמָיו וַיְּבַקֵּשׁ לִבְכּוֹת הַמְאֹרָע. וַיְּהִי כִּקְרֹא מֶלֶךְ יִשְׂרָאֵל אֶת הַסֵּפֶר, וַיִּקְרָע: יְהוּדִי הוֹקִיעַ, יְלָדָיו לְמַטָּה וַאֲבִיהֶם לְמַעְלָה. אִישׁ אִישׁ בְּשָׁלֹשׁ אַמּוֹת, וְהָרְבִיעִית אַוֵּיר מְגֻלָּה. מִשְׁנֶה נָקָם חָזָה, וְשָׂמַח וְשָׂח תְּהִלָּה. אֹתִי הֵשִׁיב עַל כַּנִּי וְאוֹתוֹ תָלָה: וַתִּכְתֹּב אֶסְתֵּר תֹּקֶף, לִקְרוֹת כִּבְהַלֵּל מְהוֹדִים. מִלְּמַעְלָה קִיְּמוּ מַה שֶּׁקִּבְּלוּ לְמַטָּה דּוֹדִים. נֵס יְנוֹסֵס לְפַרְסֵם כְּאָז פִּלְאוֹ מַסְהִידִים. בָּעֵת הַזֹּאת רֶוַח וְהַצָּלָה יַעֲמוֹד לַיְּהוּדִים:","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, מִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לְחַטָּאִים, וּסְלִיחָה לְפוֹשְׁעִים. עֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וָרוּחַ, לֹא כְרָעָתָם תִּגְמֹל. אֵל, הוֹרֵיתָ לָּנוּ לוֹמַר שְׁלֹשׁ עֶשְׂרֵה, וּזְכָר לָנוּ הַיּוֹם בְּרִית שְׁלשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָיו מִקֶּדֶם, כְּמוֹ שֶׁכָּתוּב: וַיֵּרֶד יהוה בֶּעָנָן, וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם, יהוה:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"כִּי עִמְּךָ מְקוֹר חַיִּים, בְּאוֹרְךָ נִרְאֶה אוֹר: בְּקָרְאֵנוּ עֲנֵנוּ אֱלֹהֵי צִדְקֵנוּ, בַּצָּר הִרְחַבְתָּ לָנוּ, חָנֵּנוּ וּשְׁמַע תְּפִלָּתֵנוּ. וְעַתָּה יִגְדַּל נָא כֹּחַ אֲדֹנָי, כַּאֲשֶׁר דִּבַּרְתָּ לֵאמֹר:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"כְּרַחֵם אָב עַל בָּנִים, כֵּן תְּרַחֵם יהוה עָלֵינוּ. לַיהוה הַיְּשׁוּעָה, עַל עַמְּךָ בִרְכָתֶךָ סֶּלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶּלָה: יהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אַתָּה הָאֵל עוֹשֵׂה פְלָאוֹת, בָּעַמִּים הוֹדַעְתָּ עֹז נוֹרָאוֹת, גָאַלְתָּ בִּזְרוֹעַ עַמְּךָ מִתְּלָאוֹת, דִּכִּיתָ צָרֵיהֶם בְּמוֹתֵי תַחֲלוּאוֹת. הָאוֹיֵב בְּקוּמוֹ לְעוֹרֵר מְדָנִים, וְדִמָּה לְהַכְרִית פִּרְחֵי עֲדָנִים, זָמַם לִשְׁקֹל לְגִנְזֵי אֲדוֹנִים, חֲלִיפֵי מְאַת כִּכְּרֵי אֲדָנִים. טְלָאֶיךָ הִזְהַרְתָּ שִׁקְלֵיהֶם לְהַקְדִּים, יָדַעְתָּ הָעֲתִידוֹת וְדָרַשְׁתָּ נִשְׁקָדִים, כִּבּוּי לְהַמְצִיא לְלַהַב יוֹקְדִים, לְקוּחִים לַמָּוֶת לְתֶחִי נִפְקָדִים. מַסֵּכָה צָרָה בְּעָבְדָם לְפָנִים, נִמְסְרוּ לְהָתֵז קְנוֹקְנוֹת וּגְפָנִים, סְבָבוּם מוֹקְשִׁים בְּכָל דְּפָנִים, עֵינֵיהֶם לְךָ תוֹלִים וּבְסִתְרְךָ נִצְפָּנִים. פּוּר נֶהְפַּךְ בְּאוֹיְבִים לִשְׁלֹט, צְלִיבָה הוּכַן אֲגָגִי לִקְלֹט, קַלַּע וּבַלַּע פְּנֵי הַלּוֹט הַלּוֹט, רִיבֵי עָם בְּאַשְׁמַנִּים לַעֲלֹט. שָׁלוֹם וֶאֱמֶת נִכְתַּב מִכָּל צַד, תֹּקֶף יֶשַׁע סֶלַע וּמְצָד, שׁוֹדֵד הֻשְׁדַּד וּבְרִשְׁתּוֹ נוֹצַד, מְלָשְׁנִי נִסְחַף נִצְמַת וְנִרְצָד. עָשׂוּ שְׂמָחוֹת וְלַדּוֹרוֹת קְבָעוּם, וּמִקְרָאוֹת שִׁלְּשׁוּם וְלֹא רִבְּעוּם, נִסְכְּמוּ מִמַּעַל וּלְמַטָּה טְבָעוּם, בַּסֵּפֶר נֶחֱקַק עַל מָה קְבָעוּם. רָמָה יָדְךָ לִסְלוֹחַ לַפּוֹשְׁעִים, יְהוּדִי וַהֲדַסָּה הֵקַמְתָּ מוֹשִׁיעִים, צִדְקָתָם עוֹמֶדֶת לָעַד לְשַׁעֲשׁוּעִים, חֵקֶר כְּבוֹדָם לְהִזָּכֵר לְנוֹשָׁעִים. קַנֵּא לְשִׁמְךָ נוֹרָא וְנִקְדָּשׁ, חֲזֵה כַרְמְךָ נֶהֱרַס וְנִדָּשׁ, זְרוּיֵינוּ קַבֵּץ וְשִׁיר לְךָ יְחֻדָּשׁ, קַיְּמֵם וְהַחֲיֵם בְּבִנְיַן בֵּית הַמִּקְדָּשׁ. וְכַעֲשׂוֹתְךָ נוֹרָאוֹת בְּאוֹתָן הַיָּמִים, אִתָּנוּ הַפְלֵא תְּשׁוּעַת עוֹלָמִים, מְצוֹא לְפָנֶיךָ כֹּפֶר וְתַנְחוּמִים, אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, מִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לְחַטָּאִים, וּסְלִיחָה לְפוֹשְׁעִים. עֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וָרוּחַ, לֹא כְרָעָתָם תִּגְמֹל. אֵל, הוֹרֵיתָ לָּנוּ לוֹמַר שְׁלֹשׁ עֶשְׂרֵה, וּזְכָר לָנוּ הַיּוֹם בְּרִית שְׁלשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָיו מִקֶּדֶם, כְּמוֹ שֶׁכָּתוּב: וַיֵּרֶד יהוה בֶּעָנָן, וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם, יהוה:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"הַאֲזִינָה, יהוה, תְּפִלָּתֵנוּ וְהַקְשִׁיבָה בְּקוֹל תַּחֲנוּנוֹתֵינוּ. שְׁמַע יהוה קוֹלֵנוּ נִקְרָא, וְחָנֵנוּ וַעֲנֵנוּ. שִׁמְעָה יהוה צֶדֶק, הַקְשִׁיבָה רִנָּתֵנוּ, הַאֲזִינָה תְפִלָּתֵנוּ. שְׁמַע, יהוה, וְחָנֵנוּ. יהוה, הֱיֵה עוֹזֵר לָנוּ.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"כְּרַחֵם אָב עַל בָּנִים, כֵּן תְּרַחֵם יהוה עָלֵינוּ. לַיהוה הַיְּשׁוּעָה, עַל עַמְּךָ בִרְכָתֶךָ סֶּלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶּלָה: יהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"פזמון. שליח הציבור אומר את הבית הראשון, והקהל חוזר אחריו, ולאחר מכן כל בית הקהל אומר ושליח הציבור חוזר.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"בִּמְתֵי מִסְפָּר חִלִּינוּ פָנֶיךָ, לְשַׁוְעַת נְכֵאִים אַל תַּעְלֵם אָזְנֶךָ, הַקְשֵׁב תְּחִנָּתָם מִשְּׁמֵי מְעוֹנֶךָ, כְּבִימֵי מֹר וַהֲדַס הוֹשַׁעְתָּ בָנֶיךָ.\n\nתְּהִלּוֹת יִשְׂרָאֵל אַתָּה יוֹשֵׁב, שַׁוְעָתָם מַאֲזִין וְרִנָּתָם קוֹשֵׁב, רִפְאוּת לְמַחַץ מַקְדִּים וּמְחַשֵּׁב, קְנוּיֶיךָ לְהֵיטִיב וְנָוֵיהֶם לְיַשֵּׁב.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"בִּמְתֵי מִסְפָּר חִלִּינוּ פָנֶיךָ.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"צָר וְאוֹיֵב הִלְטִישׁ עֵינָיו, פִּיהוּ פָעַר לִשְׁאֹף עָנָו, עִשֵּׁת בְּשֶׁלּוֹ לְהַשְׁמִיד קְהַל הֲמוֹנָיו, סֶגֶל לְאַבֵּד חָרַת בְּנִשְׁתְּוָנָיו.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"בִּמְתֵי מִסְפָּר חִלִּינוּ פָנֶיךָ.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"נוֹקֵם לְצָרִים וְנוֹטֵר לְאוֹיְבִים, מָדַדְתָּ מִדָּתָם כְּזָדוּ לַאֲהוּבִים, לוֹחֵם וְנִינָיו הֻתְלוּ מֻצְלָבִים, כְּבַחֲרֹזֶת דָּגִים חֹרְזוּ תְחוּבִים.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"בִּמְתֵי מִסְפָּר חִלִּינוּ פָנֶיךָ.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"יוֹם אֲשֶׁר שִׂבְּרוּ צוֹרְרִים, טִבְחָה לָשִׁית בְּעַם נְצוּרִים, חֻלְּפָה הַדָּת וְנָפְלוּ פְגָרִים, זֻלְעֲפוּ זֹעֲמוּ מוּבָסִים מֻגָּרִים.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"בִּמְתֵי מִסְפָּר חִלִּינוּ פָנֶיךָ.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"וּבְכֵן יִתְעַלֶּה שִׁמְךָ וְיִתְנַשָּׂא, הוֹדְךָ שְׁמֵי שָׁמַיִם כִּסָּה, דַּכִּים בְּרוֹמִמְךָ נְתוּנִים לִמְשִׁסָּה, גֵּיא וַאֲפָסֶיהָ תְּהִלָּתְךָ מְכַסָּה.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"בִּמְתֵי מִסְפָּר חִלִּינוּ פָנֶיךָ.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"בִּינָה הֲגִינֵנוּ עַתָּה וּרְאֵה בַצָּר, בְּאַפְּךָ קוּמָה עַל צוֹרֵר הַצָּר, אָדוֹן, קְרָאנוּךָ מִן הַמֵּצָר, אָנָּא הוֹצִיאֵנוּ לַמֶּרְחָב וְחַלְּצֵנוּ מִצָּר.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"בִּמְתֵי מִסְפָּר חִלִּינוּ פָנֶיךָ.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"מְאֹד תַּרְבֶּה לָּנוּ מְחִילָה, שְׁמַע תְּפִלָּה וְהַעֲבֵר תִּפְלָה, לוֹחֲצֵינוּ הַמְעַד וּמַלְּאֵם חַלְחָלָה, מִמֶּנּוּ רַחֲמֶיךָ לָעַד לֹא תִכְלָא.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"בִּמְתֵי מִסְפָּר חִלִּינוּ פָנֶיךָ.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, מִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לְחַטָּאִים, וּסְלִיחָה לְפוֹשְׁעִים. עֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וָרוּחַ, לֹא כְרָעָתָם תִּגְמֹל. אֵל, הוֹרֵיתָ לָּנוּ לוֹמַר שְׁלֹשׁ עֶשְׂרֵה, וּזְכָר לָנוּ הַיּוֹם בְּרִית שְׁלשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָיו מִקֶּדֶם, כְּמוֹ שֶׁכָּתוּב: וַיֵּרֶד יהוה בֶּעָנָן, וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם, יהוה:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"זְכֹר רַחֲמֶיךָ יהוה וַחֲסָדֶיךָ, כִּי מֵעוֹלָם הֵמָּה: זָכְרֵנוּ יהוה בִּרְצוֹן עַמֶּךָ, פָּקְדֵנוּ בִּישׁוּעָתֶךָ. זְכֹר עֲדָתְךָ קָנִיתָ קֶדֶם, גָּאַלְתָּ שֵׁבֶט נַחֲלָתֶךָ, הַר צִיּוֹן זֶה שָׁכַנְתָּ בּוֹ: זְכֹר יהוה חִבַּת יְרוּשָׁלָיִם, אַהֲבַת צִיּוֹן אַל תִּשְׁכַּח לָנֶצַח. אַתָּה תָקוּם תְּרַחֵם צִיּוֹן, כִּי עֵת לְחֶנְנָהּ, כִּי בָא מוֹעֵד: זְכֹר יהוה לִבְנֵי אֱדוֹם אֵת יוֹם יְרוּשָׁלָיִם, הָאוֹמְרִים עָרוּ עָרוּ, עַד הַיְסוֹד בָּהּ: זְכֹר לְאַבְרָהָם לְיִצְחָק וּלְיִשְׂרָאֵל עֲבָדֶיךָ, אֲשֶׁר נִשְׁבַּעְתָּ לָהֶם בָּךְ, וַתְּדַבֵּר אֲלֵהֶם, אַרְבֶּה אֶת זַרְעֲכֶם כְּכוֹכְבֵי הַשָּׁמַיִם, וְכָל הָאָרֶץ הַזֹּאת אֲשֶׁר אָמַרְתִּי אֶתֵּן לְזַרְעֲכֶם, וְנָחֲלוּ לְעוֹלָם: זְכֹר לַעֲבָדֶיךָ לְאַבְרָהָם לְיִצְחָק וּלְיַעֲקֹב, אַל תֵּפֶן אֶל קְשִׁי הָעָם הַזֶּה וְאֶל רִשְׁעוֹ וְאֶל חַטָּאתוֹ:\n\nאַל נָא תָשֵׁת עָלֵינוּ חַטָּאת אֲשֶׁר נוֹאַלְנוּ וַאֲשֶׁר חָטָאנוּ: חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"יש המוסיפים פיוט זה ואומרים אותו בית בית עם שליח הציבור:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"אֵל נָא, רְפָא נָא תַּחֲלוּאֵי גֶפֶן פּוֹרִיָּה, בּוֹשָׁה וַחֲפוּרָה וְאֻמְלַל פִּרְיָהּ, גְּאָלֶנָּה מִשַּׁחַת וּמִמַּכָּה טְרִיָּה, עֲנֵנוּ כְּשֶׁעָנִיתָ לְאַבְרָהָם אָבִינוּ בְּהַר הַמּוֹרִיָּה.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"דִּגְלֵי עָם פְּדוּיֵי בִּזְרוֹעַ חָשׂוּף, הַצֵּל מִנֶּגֶף וְאַל יִהְיוּ לְשִׁסּוּף, וְתַעֲנֶה קְרִיאָתֵנוּ וּלְמַעֲשֵׂה יָדֶיךָ תִּכְסֹף, עֲנֵנוּ כְּשֶׁעָנִיתָ לַאֲבוֹתֵינוּ עַל יַם סוּף.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"זְכוּת צוּר חֻצַּב הַיּוֹם לָנוּ תְגַל, חָשְׂכֵנוּ מֵאֶנֶף וּנְחֵנוּ בְּיֹשֶׁר מַעְגָּל, טַהֵר טֻמְאָתֵנוּ וְלִמְאוֹר תּוֹרָתְךָ עֵינֵינוּ גַל, עֲנֵנוּ כְּשֶׁעָנִיתָ לִיהוֹשֻׁעַ בַּגִּלְגָּל.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"יָהּ, רְאֵה דֶשֶׁן עָקוּד וְהַצְמַח לָנוּ תְרוּפָה, כַּלֵּה שׁוֹד וָשֶׁבֶר, סַעַר וְסוּפָה, לַמְּדֵנוּ וְחַכְּמֵנוּ אִמְרָתְךָ הַצְּרוּפָה, עֲנֵנוּ כְּשֶׁעָנִיתָ לִשְׁמוּאֵל בַּמִּצְפָּה.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"מֻתְמָם מֵרֶחֶם שָׁרָשָׁיו אַל תַּקְמֵל, נַקֵּנוּ מִכֶּתֶם וְשֶׁמֶץ וְלֹא נֵאָמֵל, סְעָדֵנוּ וְנִוָּשֵׁעָה וְאָרְחוֹת חֲסָדֶיךָ נִגָּמֵל, עֲנֵנוּ כְּשֶׁעָנִיתָ לְאֵלִיָּהוּ בְּהַר הַכַּרְמֶל.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"עוֹדְדֵנוּ בְּצֶדֶק מָשׁוּי מִמַּיִם וְכַפֵּר זָדוֹן וּמְשׁוּגָה, פְּדֵנוּ מִמְּהוּמַת מָוֶת וְאָחוֹר בַּל נִסּוֹגָה, צַוֵּה יְשׁוּעָתֵנוּ וּבַעֲוׂנוֹתֵינוּ אַל נִתְמוֹגְגָה, עֲנֵנוּ כְּשֶׁעָנִיתָ לְיוֹנָה בִּמְעֵי הַדָּגָה.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"קְדֻשַּׁת אִישׁ חֲסִידֶךָ זְכֹר לִיפַת פַּעֲמַיִם, רַחֲמֶיךָ תְּעוֹרֵר כִּי לָקִינוּ בְּכִפְלַיִם, שׁוּבֵנוּ תֹּקֶף לְיִרְאָתֶךָ וְלֹא נֵחָשֵׂף שׁוּלַיִם, עֲנֵנוּ כְּשֶׁעָנִיתָ לְדָוִד וְלִשְׁלֹמֹה בְנוֹ בִּירוּשָׁלַיִם.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"בתענית אסתר יש מוסיפים:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"תַּעֲנֶה לְקוֹרְאֶיךָ וְהַסְכֵּת מִמְּעוֹנִים, תִּשְׁמַע שַׁוְעַת צוֹעֲקֶיךָ, שׁוֹמֵעַ אֶל אֶבְיוֹנִים, תְּרַחֵם עַל בָּנֶיךָ כְּרַחֵם אָב עַל בָּנִים, עֲנֵנוּ כְּמוֹ שֶׁעָנִיתָ לְמָרְדְּכַי וְאֶסְתֵּר, וְתָלוּ עַל עֵץ חֲמִשִּׁים הָאָב עִם הַבָּנִים.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"חָטָאנוּ צוּרֵנוּ סְלַח לָנוּ יוֹצְרֵנוּ.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"מכאן כולם אומרים:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"זְכֹר לָנוּ בְּרִית אָבוֹת כַּאֲשֶׁר אָמַרְתָּ: וְזָכַרְתִּי אֶת בְּרִיתִי יַעֲקוֹב וְאַף אֶת בְּרִיתִי יִצְחָק וְאַף אֶת בְּרִיתִי אַבְרָהָם אֶזְכֹּר, וְהָאָרֶץ אֶזְכֹּר:\n\nזְכֹר לָנוּ בְּרִית רִאשׁוֹנִים כַּאֲשֶׁר אָמַרְתָּ: וְזָכַרְתִּי לָהֶם בְּרִית רִאשׁוֹנִים אֲשֶׁר הוֹצֵאתִי אוֹתָם מֵאֶרֶץ מִצְרַיִם לְעֵינֵי הַגּוֹיִם לִהְיוֹת לָהֶם לֵאלֹהִים, אֲנִי יהוה:\n\nעֲשֵׂה עִמָּנוּ כְּמָה שֶׁהִבְטַחְתָּנוּ: וְאַף גַּם זֹאת בִּהְיוֹתָם בְּאֶרֶץ אוֹיְבֵיהֶם לֹא מְאַסְתִּים וְלֹא גְעַלְתִּים לְכַלּוֹתָם לְהָפֵר בְּרִיתִי אִתָּם, כִּי אֲנִי יהוה אֱלֹהֵיהֶם: הָשֵׁב שְׁבוּתֵנוּ וְרַחֲמֵנוּ כְּמָה שֶׁכָּתוּב: וְשָׁב יהוה אֱלֹהֶיךָ אֶת שְׁבוּתְךָ וְרִחֲמֶךָ, וְשָׁב וְקִבֶּצְךָ מִכָּל הָעַמִּים אֲשֶׁר הֱפִיצְךָ יהוה אֱלֹהֶיךָ שָׁמָּה: קַבֵּץ נִדָּחֵינוּ כְּמָה שֶׁכָּתוּב: אִם יִהְיֶה נִדַּחֲךָ בִּקְצֵה הַשָּׁמָיִם, מִשָּׁם יְקַבֶּצְךָ יהוה אֱלֹהֶיךָ וּמִשָּׁם יִקָּחֶךָ: מְחֵה פְשָׁעֵינוּ כָּעָב וְכֶעָנָן כְּמָה שֶׁכָּתוּב: מָחִיתִי כָעָב פְּשָׁעֶיךָ וְכֶעָנָן חַטֹּאתֶיךָ, שׁוּבָה אֵלַי כִּי גְאַלְתִּיךָ: מְחֵה פְשָׁעֵינוּ לְמַעַנְךָ כַּאֲשֶׁר אָמַרְתָּ: אָנֹכִי אָנֹכִי הוּא מֹחֶה פְשָׁעֶיךָ לְמַעֲנִי, וְחַטֹּאתֶיךָ לֹא אֶזְכֹּר: הַלְבֵּן חֲטָאֵינוּ כַּשֶּׁלֶג וְכַצֶּמֶר כְּמָה שֶׁכָּתוּב: לְכוּ נָא וְנִוָּכְחָה יֹאמַר יהוה, אִם יִהְיוּ חֲטָאֵיכֶם כַּשָּׁנִים כַּשֶּׁלֶג יַלְבִּינוּ, אִם יַאְדִּימוּ כַתּוֹלָע כַּצֶּמֶר יִהְיוּ: זְרֹק עָלֵינוּ מַיִם טְהוֹרִים וְטַהֲרֵנוּ כְּמָה שֶׁכָּתוּב: וְזָרַקְתִּי עֲלֵיכֶם מַיִם טְהוֹרִים וּטְהַרְתֶּם, מִכֹּל טֻמְאֹתֵיכֶם וּמִכָּל גִּלּוּלֵיכֶם אֲטַהֵר אֶתְכֶם: רַחֵם עָלֵינוּ וְאַל תַּשְׁחִיתֵנוּ כְּמָה שֶׁכָּתוּב: כִּי אֵל רַחוּם יהוה אֱלֹהֶיךָ, לֹא יַרְפְּךָ וְלֹא יַשְׁחִיתֶךָ, וְלֹא יִשְׁכַּח אֶת בְּרִית אֲבֹתֶיךָ אֲשֶׁר נִשְׁבַּע לָהֶם: מוֹל אֶת לְבָבֵנוּ לְאַהֲבָה אֶת שְׁמֶךָ כְּמָה שֶׁכָּתוּב: וּמָל יהוה אֱלֹהֶיךָ אֶת לְבָבְךָ וְאֶת לְבַב זַרְעֶךָ, לְאַהֲבָה אֶת יהוה אֱלֹהֶיךָ בְּכָל לְבָבְךָ וּבְכָל נַפְשְׁךָ, לְמַעַן חַיֶּיךָ: הִמָּצֵא לָנוּ בְּבַקָּשָׁתֵנוּ כְּמָה שֶׁכָּתוּב: וּבִקַּשְׁתֶּם מִשָּׁם אֶת יהוה אֱלֹהֶיךָ וּמָצָאתָ, כִּי תִדְרְשֶׁנּוּ בְּכָל לְבָבְךָ וּבְכָל נַפְשֶׁךָ: תְּבִיאֵנוּ אֶל הַר קָדְשֶׁךָ וְשַׂמְּחֵנוּ בְּבֵית תְּפִלָּתֶךָ כְּמָה שֶׁכָּתוּב: וַהֲבִיאוֹתִים אֶל הַר קָדְשִׁי וְשִׂמַּחְתִּים בְּבֵית תְּפִלָּתִי, עוֹלוֹתֵיהֶם וְזִבְחֵיהֶם לְרָצוֹן עַל מִזְבְּחִי, כִּי בֵיתִי, בֵּית תְּפִלָּה יִקָּרֵא לְכָל הָעַמִּים:","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"פותחים את ארון הקודש ואמורים משפט משפט. יש קהילות בהם סדר המשפטים שונה וברוב הקהילות מדלגים על המשפט \"יהיו לרצון\".","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"שְׁמַע קוֹלֵנוּ, יהוה אֱלֹהֵינוּ, חוּס וְרַחֵם עָלֵינוּ, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ. הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם: אֲמָרֵינוּ הַאֲזִינָה יהוה, בִּינָה הֲגִיגֵנוּ. יִהְיוּ לְרָצוֹן אִמְרֵי פִינוּ וְהֶגְיוֹן לִבֵּנוּ לְפָנֶיךָ, יהוה צוּרֵנוּ וְגוֹאֲלֵנוּ. אַל תַּשְׁלִיכֵנוּ מִלְּפָנֶיךָ, וְרוּחַ קָדְשְׁךָ אַל תִּקַּח מִמֶּנּוּ. אַל תַּשְׁלִיכֵנוּ לְעֵת זִקְנָה, כִּכְלוֹת כֹּחֵנוּ אַל תַּעַזְבֵנוּ.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"מכאן מפסיקים לומר עם החזן בקול.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"אַל תַּעַזְבֵנוּ יהוה, אֱלֹהֵינוּ אַל תִּרְחַק מִמֶּנוּ. עֲשֵׂה עִמָּנוּ אוֹת לְטוֹבָה, וְיִרְאוּ שׂוֹנְאֵינוּ וְיֵבוֹשׁוּ, כִּי אַתָּה יהוה עֲזַרְתָּנוּ וְנִחַמְתָּנוּ. כִּי לְךָ יהוה הוֹחָלְנוּ, אַתָּה תַעֲנֶה אֲדֹנָי אֱלֹהֵינוּ.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"סוגרים את ארון הקודש.","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, תָּבוֹא לְפָנֶיךָ תְּפִלָּתֵנוּ וְאַל תִּתְעַלַּם מִתְּחִנָּתֵנוּ, שֶׁאֵין אָנוּ עַזֵּי פָנִים וּקְשֵׁי עֹרֶף לוֹמַר לְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ צַדִּיקִים אֲנַחְנוּ וְלֹא חָטָאנוּ, אֲבָל אֲנַחְנוּ וַאֲבוֹתֵינוּ חָטָאנוּ.\nאָשַׁמְנוּ, בָּגַדְנוּ, גָּזַלְנוּ, דִּבַּרְנוּ דֹפִי. הֶעֱוִינוּ, וְהִרְשַׁענוּ, זַדְנוּ, חָמַסְנוּ, טָפַלְנוּ שֶׁקֶר. יָעַצְנוּ רָע, כְּזַּבְנוּ, לַצְנוּ, מָרַדְנוּ, נִאַצְנוּ, סָרַרְנוּ, עָוְינוּ, פָּשַׁעְנוּ, צָרַרְנוּ, קִשִּׁינוּ עֹרֶף. רָשַׁעְנוּ, שִׁחַתְנוּ, תִּעַבְנוּ, תָּעִינוּ, תִּעְתַּעְנוּ.\nסַרְנוּ מִמִּצְוׂתֶיךָ וּמִמִּשְׁפָּטֶיךָ הַטּוֹבִים וְלֹא שָׁוָה-לָנוּ. וְאַתָּה צַדִּיק עַל כָּל הַבָּא עָלֵינוּ, כִּי אֱמֶת עָשִׂיתָ, וַאֲנַחְנוּ הִרְשָׁעְנוּ:\n\nהִרְשַׁעְנוּ וּפָשַׁעְנוּ לָכֵן לֹא נוֹשָׁעְנוּ. וְתֵן בְּלִבֵּנוּ לַעֲזֹב דֶּרֶךְ רֶשַׁע, וְחִישׁ לָנוּ יֶשַׁע, כַּכָּתוּב עַל יַד נְבִיאֶךָ: יַעֲזוֹב רָשָׁע דַּרְכּוֹ וְאִישׁ אָוֶן מַחְשְׁבֹתָיו, וְיָשֹׁב אֶל יהוה וִירַחֲמֵהוּ, וְאֶל אֱלֹהֵינוּ כִּי יַרְבֶּה לִסְלוֹחַ:\n\nמְשִׁיחַ צִדְקֶךָ אָמַר לְפָנֶיךָ: שְׁגִיאוֹת מִי יָבִין מִנִּסְתָּרוֹת נַקֵּנִי: נַקֵּנוּ יהוה אֱלֹהֵינוּ מִכָּל פְּשָׁעֵינוּ וְטַהֲרֵנוּ מִכָּל טֻמְאוֹתֵינוּ, וּזְרֹק עָלֵינוּ מַיִם טְהוֹרִים וְטַהֲרֵנוּ, כַּכָּתוּב עַל יַד נְבִיאֶךָ: וְזָרַקְתִּי עֲלֵיכֶם מַיִם טְהוֹרִים וּטְהַרְתֶּם, מִכֹּל טֻמְאוֹתֵיכֶם וּמִכָּל גִּלּוּלֵיכֶם אֲטַהֵר אֶתְכֶם: עַמְּךָ וְנַחֲלָתְךָ רְעֵבֵי טוּבְךָ, צְמֵאֵי חַסְדְּךָ, תְּאֵבֵי יִשְׁעֶךָ. יַכִּירוּ וְיֵדְעוּ כִּי לַיהוה אֱלֹהֵינוּ הָרַחֲמִים וְהַסְּלִיחוֹת.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"אם אין אומרים תחנון מדלגים על המשך הסליחות.","cond":["shacharitTachanun","ester","shacharitTachanun"]},{"kind":"text","text":"אֵל רַחוּם שְׁמֶךָ. אֵל חַנּוּן שְׁמֶךָ. בָּנוּ נִקְרָא שְׁמֶךָ. יהוה עֲשֵׂה לְמַעַן שְׁמֶךָ. עֲשֵׂה לְמַעַן אֲמִתָּךְ. עֲשֵׂה לְמַעַן בְּרִיתָךְ. עֲשֵׂה לְמַעַן גָּדְלָךְ וְתִפְאַרְתָּךְ. עֲשֵׂה לְמַעַן דָּתָךְ. עֲשֵׂה לְמַעַן הוֹדָךְ. עֲשֵׂה לְמַעַן וִעוּדָךְ. עֲשֵׂה לְמַעַן זִכְרָךְ. עֲשֵׂה לְמַעַן חַסְדָּךְ. עֲשֵׂה לְמַעַן טוּבָךְ. עֲשֵׂה לְמַעַן יִחוּדָךְ. עֲשֵׂה לְמַעַן כְּבוֹדָךְ. עֲשֵׂה לְמַעַן לִמּוּדָךְ. עֲשֵׂה לְמַעַן מַלְכוּתָךְ. עֲשֵׂה לְמַעַן נִצְחָךְ. עֲשֵׂה לְמַעַן סוֹדָךְ. עֲשֵׂה לְמַעַן עֻזָּךְ. עֲשֵׂה לְמַעַן פְּאֵרָךְ. עֲשֵׂה לְמַעַן צִדְקָתָךְ. עֲשֵׂה לְמַעַן קְדֻשָׁתָךְ. עֲשֵׂה לְמַעַן רַחֲמֶיךָ הָרַבִּים. עֲשֵׂה לְמַעַן שְׁכִינָתָךְ. עֲשֵׂה לְמַעַן תְּהִלָּתָךְ. עֲשֵׂה לְמַעַן אוֹהֲבֶיךָ שׁוֹכְנֵי עָפָר. עֲשֵׂה לְמַעַן אַבְרָהָם יִצְחָק וְיַעֲקֹב. עֲשֵׂה לְמַעַן מֹשֶׁה וְאַהֲרֹן. עֲשֵׂה לְמַעַן דָּוִד וּשְׁלֹמֹה. עֲשֵׂה לְמַעַן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ. עֲשֵׂה לְמַעַן צִיּוֹן מִשְׁכַּן כְּבוֹדֶךָ. עֲשֵׂה לְמַעַן שִׁמְמוֹת הֵיכָלֶךָ. עֲשֵׂה לְמַעַן הֲרִיסוּת מִזְבְּחֶךָ. עֲשֵׂה לְמַעַן הֲרוּגִים עַל שֵׁם קָדְשֶׁךָ. עֲשֵׂה לְמַעַן טְבוּחִים עַל יִחוּדֶךָ. עֲשֵׂה לְמַעַן בָּאֵי בָאֵשׁ וּבַמַּיִם עַל קִדּוּשׁ שְׁמֶךָ. עֲשֵׂה לְמַעַן יוֹנְקֵי שָׁדַיִם שֶׁלֹּא חָטְאוּ. עֲשֵׂה לְמַעַן גְּמוּלֵי חָלָב שֶׁלֹּא פָשְׁעוּ. עֲשֵׂה לְמַעַן תִּינוֹקוֹת שֶׁל בֵּית רַבָּן. עֲשֵׂה לְמַעַנְךָ אִם לֹא לְמַעֲנֵנוּ. עֲשֵׂה לְמַעַנְךָ וְהוֹשִׁיעֵנוּ.\n\nעֲנֵנוּ יהוה עֲנֵנוּ. עֲנֵנוּ אֱלֹהֵינוּ עֲנֵנוּ. עֲנֵנוּ אָבִינוּ עֲנֵנוּ. עֲנֵנוּ בּוֹרְאֵנוּ עֲנֵנוּ. עֲנֵנוּ גּוֹאֲלֵנוּ עֲנֵנוּ. עֲנֵנוּ דּוֹרְשֵׁנוּ עֲנֵנוּ. עֲנֵנוּ הָאֵל הַנֶּאֱמָן עֲנֵנוּ. עֲנֵנוּ וָתִיק וְחָסִיד עֲנֵנוּ. עֲנֵנוּ זַךְ וְיָשָׁר עֲנֵנוּ. עֲנֵנוּ חַי וְקַיָּם עֲנֵנוּ. עֲנֵנוּ טוֹב וּמֵטִיב עֲנֵנוּ. עֲנֵנוּ יוֹדֵעַ יֶצֶר עֲנֵנוּ. עֲנֵנוּ כּוֹבֵשׁ כְּעָסִים עֲנֵנוּ. עֲנֵנוּ לוֹבֵשׁ צְדָקוֹת עֲנֵנוּ. עֲנֵנוּ מֶלֶךְ מַלְכֵי הַמְּלָכִים עֲנֵנוּ. עֲנֵנוּ נוֹרָא וְנִשְׂגָּב עֲנֵנוּ. עֲנֵנוּ סוֹלֵחַ וּמוֹחֵל עֲנֵנוּ. עֲנֵנוּ עוֹנֶה בְּעֵת צָרָה עֲנֵנוּ. עֲנֵנוּ פּוֹדֶה וּמַצִּיל עֲנֵנוּ. עֲנֵנוּ צַדִּיק וְיָשָׁר עֲנֵנוּ. עֲנֵנוּ קָרוֹב לְקוֹרְאָיו עֲנֵנוּ. עֲנֵנוּ רַחוּם וְחַנוּן עֲנֵנוּ. עֲנֵנוּ שׁוֹמֵעַ אֶל אֶבְיוֹנִים עֲנֵנוּ. עֲנֵנוּ תּוֹמֵךְ תְּמִימִים עֲנֵנוּ. עֲנֵנוּ אֱלֹהֵי אֲבוֹתֵינוּ עֲנֵנוּ. עֲנֵנוּ אֱלֹהֵי אַבְרָהָם עֲנֵנוּ. עֲנֵנוּ פַּחַד יִצְחָק עֲנֵנוּ. עֲנֵנוּ אֲבִיר יַעֲקֹב עֲנֵנוּ. עֲנֵנוּ עֶזְרַת הַשְּׁבָטִים עֲנֵנוּ. עֲנֵנוּ מִשְׂגַּב אִמָּהוֹת עֲנֵנוּ. עֲנֵנוּ קָשֶׁה לִכְעוֹס עֲנֵנוּ. עֲנֵנוּ רַךְ לִרְצוֹת עֲנֵנוּ. עֲנֵנוּ עוֹנֶה בְּעֵת רָצוֹן עֲנֵנוּ. עֲנֵנוּ אֲבִי יְתוֹמִים עֲנֵנוּ. עֲנֵנוּ דַּיַּן אַלְמָנוֹת עֲנֵנוּ.\n\nמִי שֶׁעָנָה לְאַבְרָהָם אָבִינוּ בְּהַר הַמּוֹרִיָּה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְיִצְחָק בְּנוֹ כְּשֶׁנֶּעֱקַד עַל גַּבֵּי הַמִּזְבֵּחַ הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְיַעֲקֹב בְּבֵית אֵל הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְיוֹסֵף בְּבֵית הָאֲסוּרִים הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לַאֲבוֹתֵינוּ עַל יַם סוּף הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְמֹשֶׁה בְּחוֹרֵב הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְאַהֲרֹן בַּמַּחְתָּה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְפִינְחָס בְּקוּמוֹ מִתּוֹךְ הָעֵדָה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לִיהוֹשֻׁעַ בַּגִּלְגָּל הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לִשְׁמוּאֵל בַּמִּצְפָּה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְדָוִד וּשְׁלֹמֹה בְנוֹ בִּירוּשָׁלָיִם הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְאֵלִיָּהוּ בְּהַר הַכַּרְמֶל הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לֶאֱלִישָׁע בִּירִיחוֹ הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְיוֹנָה בִּמְעֵי הַדָּגָה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְחִזְקִיָּהוּ מֶלֶךְ יְהוּדָה בְּחָלְיוֹ הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לַחֲנַנְיָה מִישָׁאֵל וַעֲזַרְיָה בְּתוֹךְ כִּבְשַׁן הָאֵשׁ הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְדָנִיֵּאל בְּגוֹב הָאֲרָיוֹת הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְמָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְעֶזְרָא בַּגּוֹלָה הוּא יַעֲנֵנוּ. מִי שֶׁעָנָה לְכָל הַצַּדִּיקִים וְהַחֲסִידִים וְהַתְּמִימִים וְהַיְּשָׁרִים הוּא יַעֲנֵנוּ.\n\nרַחֲמָנָא דְעָנֵי לַעֲנִיֵי עֲנֵינָא. רַחֲמָנָא דְעָנֵי לִתְבִירֵי לִבָּא עֲנֵינָן. רַחֲמָנָא דְעָנֵי לְמַכִּיכֵי רוּחָא עֲנֵינָן. רַחֲמָנָא עֲנֵינָן. רַחֲמָנָא חוּס. רַחֲמָנָא פְּרוֹק. רַחֲמָנָא שְׁזִיב. רַחֲמָנָא רְחַם עֲלָן. הַשְׁתָּא בַּעֲגָלָא וּבִזְמַן קָרִיב.","cond":["shacharitTachanun","ester","shacharitTachanun"]},{"kind":"header","text":"אבינו מלכנו","cond":["shacharitTachanun","noGedalya"]},{"kind":"instruction","text":"אבינו מלכנו","cond":["shacharitTachanun","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חָטָאנוּ לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, אֵין לָנוּ מֶלֶךְ אֶלָּא אָתָּה.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה עִמָּנוּ לְמַעַן שְׁמֶךָ.","cond":["shacharitTachanun","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חַדֵּשׁ עָלֵינוּ שָׁנָה טוֹבָה.","cond":["shacharitTachanun","noGedalya","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, בָּרֵךְ עָלֵינוּ שָׁנָה טוֹבָה.","cond":["shacharitTachanun","noGedalya","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, בַּטֵּל מֵעָלֵינוּ כָּל גְּזֵרוֹת קָשׁוֹת.\nאָבִינוּ מַלְכֵּנוּ, בַּטֵּל מַחְשְׁבוֹת שׂוֹנְאֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, הָפֵר עֲצַת אוֹיְבֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה כָּל צַר וּמַשְׂטִין מֵעָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, סְתֹם פִּיּוֹת מַשְׂטִינֵינוּ וּמְקַטְרְגֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה דֶבֶר וְחֶרֶב וְרָעָב וּשְׁבִי וּמַשְׁחִית וְעָוׂן וּשְׁמַד מִבְּנֵי בְרִיתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, מְנַע מַגֵּפָה מִנַּחֲלָתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, סְלַח וּמְחַל לְכָל עֲוׂנוֹתֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, מְחֵה וְהַעֲבֵר פְּשָׁעֵינוּ וְחַטֹּאתֵינוּ מִנֶּגֶד עֵינֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, מְחֹק בְּרַחֲמֶיךָ הָרַבִּים כָּל שִׁטְרֵי חוֹבוֹתֵינוּ.","cond":["shacharitTachanun","noGedalya"]},{"kind":"instruction","text":"מכאן אומרים בקול עם החזן","cond":["shacharitTachanun","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, הַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, שְׁלַח רְפוּאָה שְׁלֵמָה לְחוֹלֵי עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, קְרַע רֹע גְּזַר דִּינֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ בְּזִכְרוֹן טוֹב לְפָנֶיךָ.","cond":["shacharitTachanun","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר חַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר גְּאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר פַּרְנָסָה וְכַלְכָּלָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר זְכֻיּוֹת.\nאָבִינוּ מַלְכֵּנוּ, כָָּתְבֵנוּ בְּסֵפֶר סְלִיחָה וּמְחִילָה.","cond":["shacharitTachanun","noGedalya","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לְחַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִגְאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לְפַרְנָסָה וְכַלְכָּלָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִזְכֻיּוֹת.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִסְלִיחָה וּמְחִילָה.","cond":["shacharitTachanun","noGedalya","noGedalya"]},{"kind":"instruction","text":"עד כאן עם החזן","cond":["shacharitTachanun","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, הַצְמַח לָנוּ יְשׁוּעָה בְּקָרוֹב.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן יִשְׂרָאֵל עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן מְשִׁיחֶךָ.\nאָבִינוּ מַלְכֵּנוּ, מַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, מַלֵּא אֲסָמֵינוּ שָׂבָע.\nאָבִינוּ מַלְכֵּנוּ, שְׁמַע קוֹלֵנוּ, חוּס וְרַחֵם עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, קַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, פְּתַח שַׁעֲרֵי שָׁמַיִם לִתְפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, זְכֹר כִּי עָפָר אֲנַחְנוּ.\nאָבִינוּ מַלְכֵּנוּ, נָא אַל תְּשִׁיבֵנוּ רֵיקָם מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, תְּהֵא הַשָּׁעָה הַזֹּאת שְׁעַת רַחֲמִים וְעֵת רָצוֹן מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, חֲמֹל עָלֵינוּ וְעַל עוֹלָלֵינוּ וְטַפֵּנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן הֲרוּגִים עַל שֶׁם קָדְשֶׁךָ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן טְבוּחִים עַל יִחוּדֶךָ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן בָּאֵי בָאֵשׁ וּבַמָּיִּם עַל קִדּוּשׁ שְׁמֶךָ.\nאָבִינוּ מַלְכֵּנוּ, נְקֹם נִקְמַת דַּם עֲבָדֶיךָ הַשָּׁפוּךְ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַנְךָ אִם לֹא לְמַעַנֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַנְךָ וְהוֹשִׁיעֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַן רַחֲמֶיךָ הָרַבִּים.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַן שִׁמְךָ הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא שֶׁנִּקְרָא עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, חָנֵּנוּ וַעֲנֵנוּ כִּי אֵין בָּנוּ מַעֲשִׂים, עֲשֵׂה עִמָּנוּ צְדָקָה וָחֶסֶד וְהוֹשִׁיעֵנוּ.","cond":["shacharitTachanun","noGedalya"]},{"kind":"header","text":"אבינו מלכנו","cond":["shacharitTachanun","ayt"]},{"kind":"instruction","text":"אבינו מלכנו","cond":["shacharitTachanun","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חָטָאנוּ לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, אֵין לָנוּ מֶלֶךְ אֶלָּא אָתָּה.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה עִמָּנוּ לְמַעַן שְׁמֶךָ.","cond":["shacharitTachanun","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חַדֵּשׁ עָלֵינוּ שָׁנָה טוֹבָה.","cond":["shacharitTachanun","ayt","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, בָּרֵךְ עָלֵינוּ שָׁנָה טוֹבָה.","cond":["shacharitTachanun","ayt","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, בַּטֵּל מֵעָלֵינוּ כָּל גְּזֵרוֹת קָשׁוֹת.\nאָבִינוּ מַלְכֵּנוּ, בַּטֵּל מַחְשְׁבוֹת שׂוֹנְאֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, הָפֵר עֲצַת אוֹיְבֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה כָּל צַר וּמַשְׂטִין מֵעָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, סְתֹם פִּיּוֹת מַשְׂטִינֵינוּ וּמְקַטְרְגֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה דֶבֶר וְחֶרֶב וְרָעָב וּשְׁבִי וּמַשְׁחִית וְעָוׂן וּשְׁמַד מִבְּנֵי בְרִיתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, מְנַע מַגֵּפָה מִנַּחֲלָתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, סְלַח וּמְחַל לְכָל עֲוׂנוֹתֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, מְחֵה וְהַעֲבֵר פְּשָׁעֵינוּ וְחַטֹּאתֵינוּ מִנֶּגֶד עֵינֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, מְחֹק בְּרַחֲמֶיךָ הָרַבִּים כָּל שִׁטְרֵי חוֹבוֹתֵינוּ.","cond":["shacharitTachanun","ayt"]},{"kind":"instruction","text":"מכאן אומרים בקול עם החזן","cond":["shacharitTachanun","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, הַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, שְׁלַח רְפוּאָה שְׁלֵמָה לְחוֹלֵי עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, קְרַע רֹע גְּזַר דִּינֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ בְּזִכְרוֹן טוֹב לְפָנֶיךָ.","cond":["shacharitTachanun","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר חַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר גְּאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר פַּרְנָסָה וְכַלְכָּלָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר זְכֻיּוֹת.\nאָבִינוּ מַלְכֵּנוּ, כָָּתְבֵנוּ בְּסֵפֶר סְלִיחָה וּמְחִילָה.","cond":["shacharitTachanun","ayt","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לְחַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִגְאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לְפַרְנָסָה וְכַלְכָּלָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִזְכֻיּוֹת.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִסְלִיחָה וּמְחִילָה.","cond":["shacharitTachanun","ayt","noGedalya"]},{"kind":"instruction","text":"עד כאן עם החזן","cond":["shacharitTachanun","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, הַצְמַח לָנוּ יְשׁוּעָה בְּקָרוֹב.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן יִשְׂרָאֵל עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן מְשִׁיחֶךָ.\nאָבִינוּ מַלְכֵּנוּ, מַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, מַלֵּא אֲסָמֵינוּ שָׂבָע.\nאָבִינוּ מַלְכֵּנוּ, שְׁמַע קוֹלֵנוּ, חוּס וְרַחֵם עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, קַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, פְּתַח שַׁעֲרֵי שָׁמַיִם לִתְפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, זְכֹר כִּי עָפָר אֲנַחְנוּ.\nאָבִינוּ מַלְכֵּנוּ, נָא אַל תְּשִׁיבֵנוּ רֵיקָם מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, תְּהֵא הַשָּׁעָה הַזֹּאת שְׁעַת רַחֲמִים וְעֵת רָצוֹן מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, חֲמֹל עָלֵינוּ וְעַל עוֹלָלֵינוּ וְטַפֵּנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן הֲרוּגִים עַל שֶׁם קָדְשֶׁךָ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן טְבוּחִים עַל יִחוּדֶךָ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן בָּאֵי בָאֵשׁ וּבַמָּיִּם עַל קִדּוּשׁ שְׁמֶךָ.\nאָבִינוּ מַלְכֵּנוּ, נְקֹם נִקְמַת דַּם עֲבָדֶיךָ הַשָּׁפוּךְ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַנְךָ אִם לֹא לְמַעַנֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַנְךָ וְהוֹשִׁיעֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַן רַחֲמֶיךָ הָרַבִּים.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַן שִׁמְךָ הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא שֶׁנִּקְרָא עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, חָנֵּנוּ וַעֲנֵנוּ כִּי אֵין בָּנוּ מַעֲשִׂים, עֲשֵׂה עִמָּנוּ צְדָקָה וָחֶסֶד וְהוֹשִׁיעֵנוּ.","cond":["shacharitTachanun","ayt"]},{"kind":"instruction","text":"תחנונים לשני וחמישי","cond":["shacharitTachanun","monThu"]},{"kind":"text","text":"וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית, וְהִרְבָּה לְהָשִׁיב אַפּוֹ וְלֹא יָעִיר כָּל חֲמָתוֹ: אַתָּה יהוה, לֹא תִכְלָא רַחֲמֶיךָ מִמֶּנּוּ, חַסְדְּךָ וַאֲמִתְּךָ תָּמִיד יִצְּרוּנוּ. הוֹשִׁיעֵנוּ יהוה אֱלֹהֵינוּ וְקַבְּצֵנוּ מִן הַגּוֹיִם, לְהֹדוֹת לְשֵׁם קָדְשֶׁךָ, לְהִשְׁתַּבֵּחַ בִּתְהִלָּתֶךָ: אִם עֲוׂנוֹת תִּשְמָר יָהּ, אֲדֹנָי, מִי יַעֲמֹד: כִּי עִמְּךָ הַסְּלִיחָה, לְמַעַן תִּוָּרֵא: לֹא כַחֲטָאֵינוּ תַּעֲשֶׂה לָנוּ וְלֹא כַעֲוׂנֹתֵינוּ תִּגְמֹל עָלֵינוּ. אִם עֲוׂנֵינוּ עָנוּ בָנוּ, יהוה, עֲשֵׂה לְמַעַן שְׁמֶךָ. זְכֹר רַחֲמֶיךָ יהוה וַחֲסָדֶיךָ, כִּי מֵעוֹלָם הֵמָּה: יַעֲנֵנוּ יהוה בְּיוֹם צָרָה, יְשַׂגְּבֵנוּ שֵׁם אֱלֹהֵי יַעֲקֹב. יהוה הושִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ: אָבִינוּ מַלְכֵּנוּ, חָנֵּנוּ וַעֲנֵנוּ, כִּי אֵין בָּנוּ מַעֲשִׂים. עֲשה עִמָּנוּ צְדָקָה כְּרֹב רַחֲמֶיךָ וְהוֹשִׁיעֵנוּ לְמַעַן שְׁמֶךָ. אֲדוֹנֵינוּ אֱלֹהֵינוּ, שְׁמַע קוֹל תַּחֲנוּנֵינוּ, וּזְכָר לָנוּ אֶת בְּרִית אֲבוֹתֵינוּ, וְהוֹשִׁיעֵנוּ לְמַעַן שְׁמֶךָ.\n\nוְעַתָּה אֲדֹנָי אֱלֹהֵינוּ אֲשֶׁר הוֹצֵאתָ אֶת עַמְּךָ מֵאֶרֶץ מִצְרַיִם בְּיָד חֲזָקָה, וַתַּעַשׂ לְךָ שֵׁם כַּיּוֹם הַזֶּה, חָטָאנוּ רָשָׁעְנוּ: אֲדֹנָי, כְּכָל צִדְקֹתֶךָ יָשָׁב נָא אַפְּךָ וַחֲמָתְךָ מֵעִירְךָ יְרוּשָׁלַיִם הַר קָדְשֶׁךָ, כִּי בַחֲטָאֵינוּ וּבַעֲוׂנוֹת אֲבֹתֵינוּ, יְרוּשָׁלִַם וְעַמְּךָ לְחֶרְפָּה לְכָל סְבִיבֹתֵינוּ: וְעַתָּה שְׁמַע אֱלֹהֵינוּ אֶל תְּפִלַּת עַבְדְּךָ וְאֶל תַּחֲנוּנָיו, וְהָאֵר פָּנֶיךָ עַל מִקְדָּשְׁךָ הַשָּׁמֵם, לְמַעַן אֲדֹנָי: הַטֵּה אֱלֹהַי אָזְנְךָ וּשְׁמָע, פְּקַח עֵינֶיךָ וּרְאֵה שֹׁמְמֹתֵינוּ וְהָעִיר אֲשֶׁר נִקְרָא שִׁמְךָ עָלֶיהָ, כִּי לֹא עַל צִדְקֹתֵינוּ אֲנַחְנוּ מַפִּילִים תַּחֲנוּנֵינוּ לְפָנֶיךָ, כִּי עַל רַחֲמֶיךָ הָרַבִּים: אֲדֹנָי שְׁמָעָה, אֲדֹנָי סְלָחָה, אֲדֹנָי הַקֲשִׁיבָה וַעֲשֵׂה אַל תְּאַחַר, לְמַעֲנְךָ אֱלֹהַי, כִּי שִׁמְךָ נִקְרָא עַל עִירְךָ וְעַל עַמֶּךָ:\n\nאָבִינוּ אָב הָרַחֲמָן, הַרְאֵנוּ אוֹת לְטוֹבָה וְקַבֵּץ נְפוּצוֹתֵינוּ מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ. יַכִּירוּ וְיֵדְעוּ כָּל הַגּוֹיִם, כִּי אַתָּה יהוה אֱלֹהֵינוּ. וְעַתָּה יהוה אָבִינוּ אָתָּה, אֲנַחְנוּ הַחֹמֶר וְאַתָּה יֹצְרֵנוּ וּמַעֲשֵׂה יָדְךָ כֻּלָּנוּ: הוֹשִׁיעֵנוּ לְמַעַן שְׁמֶךָ, אָבִינוּ מַלְכֵּנוּ צוּרֵנוּ וְגוֹאֲלֵנוּ. חוּסָה יהוה עַל עַמֶּךָ וְאַל תִּתֵּן נַחֲלָתְךָ לְחֶרְפָּה לִמְשָׁל בָּם גּוֹיִם, לָמָּה יֹאמְרוּ בָעַמִּים אַיֵּה אֱלֹהֵיהֶם: יָדַעְנוּ יהוה כִּי חָטָאנוּ וְאֵין מִי יַעֲמֹד בַּעֲדֵנוּ, אֶלָּא שִׁמְךָ הַגָּדוֹל יַעֲמָד לָנוּ בְּעֵת צָרָה. יָדַעְנוּ כִּי אֵין בָּנוּ מַעֲשִׂים. צְדָקָה עֲשֵׂה עִמָּנוּ לְמַעַן שְׁמֶךָ. כְּרַחֵם אָב עַל בָּנִים כֵּן תְּרַחֵם יהוה עָלֵינוּ, וְהוֹשִׁיעֵנוּ לְמַעַן שְׁמֶךָ. חֲמֹל עַל עַמֶּךָ, רַחֵם עַל נַחֲלָתֶךָ, חוּסָה נָּא כְּרֹב רַחֲמֶיךָ, חָנֵנוּ מַלְכֵּנוּ וַעֲנֵנוּ. כִּי לְךָ יהוה הַצְּדָקָה, עֹשֵׂה נִפְלָאוֹת בְּכָל עֵת.\n\nהַבֶּט נָא רַחֶם נָא וְהושִׁיעָה נָּא צֹאן מַרְעִיתֶךָ, וְאַל יִמְשָׁל בָּנוּ קֶצֶף, כִּי לְךָ יהוה הַיְשׁוּעָה. בְּךָ תוֹחַלְתֵּנוּ אֱלוֹהַּ סְלִיחוֹת. אָנָּא סְלַח נָא, כִּי אֵל טוב וְסַלָּח אָתָּה.\n\nאָנָּא מֶלֶךְ חַנּוּן וְרַחוּם, זְכֹר וְהַבֵּט לִבְרִית בֵּין הַבְּתָרִים וְתֵרָאֶה לְפָנֶיךָ עֲקֵדַת יָחִיד, וּלְמַעַן יִשרָאֵל אָבִינוּ, אַל תַּעַזְבֵנוּ אָבִינוּ. וְאַל תִּטְּשֵׁנוּ מַלְכֵּנוּ, וְאַל תִּשְׁכָּחֵנוּ יוֹצְרֵנוּ, וְאַל תַּעַשׂ עִמָּנוּ כָּלָה כְּחַטֹּאתֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.\n\nאֵין כָּמוֹךָ חַנּוּן וְרַחוּם יהוה אֱלֹהֵינוּ, אֵין כָּמוֹךָ אֵל אֶרֶךְ אַפַּיִם וְרַב חֶסֶד וֶאֱמֶת, הוֹשִׁיעֵנוּ וְרַחֲמֵנוּ בְּרַחֲמֶיךָ הָרַבִּים, מֵרַעַשׁ וּמֵרֹגֶז הַצִּילֵנוּ. זְכֹר לַעֲבָדֶיךָ לְאַבְרָהָם לְיִצְחָק וּלְיַעֲקֹב. אַל תֵּפֶן אֶל קָשְׁיֵנו וְאֶל רִשְׁעֵנוּ וְאֶל חַטָּאתֵנוּ. שׁוּב מֵחֲרון אַפֶּךָ וְהִנָּחֵם עַל הָרָעָה לְעַמֶּךָ: וְהָסֵר מִמֶּנּוּ מַכַּת הַמָּוֶת כִּי רַחוּם אָתָּה, כִּי כֵן דַּרְכֶּךָ, עוֹשֶׂה חֶסֶד חִנָּם בְּכָל דּוֹר וָדוֹר. חוּסָה יהוה עַל עַמֶּךָ וְהַצִּילֵנוּ מִזַּעְמֶךָ, וְהָסֵר מִמֶּנּוּ מַכַּת הַמַּגֵּפָה וּגְזֵרָה קָשָׁה, כִּי אַתָּה שׁוֹמֵר יִשרָאֵל. לְךָ אֲדֹנָי הַצְּדָקָה וְלָנוּ בֹּשֶׁת הַפָּנִים. מַה נִּתְאוֹנֵן וּמַה נֹּאמַר מַה נְּדַבֵּר וּמַה נִּצְטַדָּק. נַחְפְּשָׂה דְרָכֵינוּ וְנַחְקֹרָה וְנָשׁוּבָה אֵלֶיךָ, כִּי יְמִינְךָ פְשׁוּטָה לְקַבֵּל שָׁבִים. אָנָּא יהוה הושִׁיעָה נָּא, אָנָּא יהוה הַצְּלִיחָה נָא: אָנָּא יהוה עֲנֵנוּ בְיוֹם קָרְאֵנוּ. \nלְךָ יהוה חִכִּינוּ, לְךָ יהוה קִוִּינוּ, לְךָ יהוה נְיַחֵל. אַל תֶּחֱשֶׁה וּתְעַנֵּנוּ, כִּי נָאֲמוּ גּוֹיִם: אָבְדָה תִקְוָתָם. כָּל בֶּרֶךְ לְךָ תִכְרַע וְכָל קומָה לְךָ לְבַד תִּשְׁתַּחֲוֶה.\n\nהַפּוֹתֵחַ יָד בִּתְשׁוּבַה לְקַבֵּל פּוֹשְׁעִים וְחַטָּאִים, נִבְהֲלָה נַפְשֵׁנוּ מֵרֹב עִצְּבוֹנֵנוּ. אַל תִּשְׁכָּחֵנוּ נֶצַח, קוּמָה וְהוֹשִׁיעֵנוּ. אַל תִּשְׁפֹּך חֲרוֹנְךָ עָלֵינוּ, כִּי אֲנַחְנוּ עַמְּךָ בְּנֵי בְרִיתֶךָ. אֵל, הַבִּיטָה, דַּל כְּבוֹדֵנוּ בַּגּוֹיִם וְשִׁקְּצוּנוּ כְּטֻמְאַת הַנִּדָּה. עַד מַתָּי עֻזְּךָ בַּשְּׁבִי, וְתִפְאַרְתְּךָ בְּיַד צָר. עוֹרְרָה גְבוּרָתֶךָ וְהוֹשִׁיעֵנוּ לְמַעַן שְׁמֶךָ. אַל יִמְעֲטוּ לְפָנֶיךָ תְּלָאוֹתֵינוּ, מַהֵר יְקַדְּמוּנוּ רַחֲמֶיךָ בְּעֵת צָרוֹתֵינוּ. לֹא לְמַעֲנֵנוּ אֶלָּא לְמַעַנְךָ פְעַל, וְאַל תַּשְׁחִית אֶת זֵכֶר שְׁאֵרִיתֵנוּ, כִּי לְךָ מְיַחֲלוֹת עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה. וּזְכֹר עֵדוּתֵנוּ בְּכָל יוֹם תָּמִיד אוֹמְרִים פַּעֲמַיִם בְּאַהֲבָה: \"שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:\"\n\nיהוה אֱלֹהֵי יִשְׂרָאֵל, שׁוּב מֵחֲרוֹן אַפֶּךָ וְהִנָּחֵם עַל הָרָעָה לְעַמֶּךָ:\nהַבֵּט מִשָּׁמַיִם וּרְאֵה כִּי הָיִינוּ לַעַג וָקֶלֶס בַגּוֹיִם, נֶחְשַׁבְנוּ כַּצֹּאן לַטֶּבַח יוּבָל, לַהֲרֹג וּלְאַבֵּד וּלְמַכָּה וּלְחֶרְפָּה.\nוּבְכָל זֹאת שִׁמְךָ לֹא שָׁכָחְנוּ, נָא אַל תִּשְׁכָּחֵנוּ.\nיהוה אֱלֹהֵי יִשְׂרָאֵל, שׁוּב מֵחֲרוֹן אַפֶּךָ וְהִנָּחֵם עַל הָרָעָה לְעַמֶּךָ:\n\nזָרִים אוֹמְרֵים אֵין תּוֹחֶלֶת וְתִקְוָה, חֹן אֹם לְשִׁמְךָ מְקַוֶּה, טָהוֹר, יְשׁוּעָתֵנוּ קָרְבָה, יָגַעְנוּ וְלֹא הוּנַח לָנוּ, רַחֲמֶיךָ יִכְבְּשׁוּ אֶת כַּעַסְךָ מֵעָלֵינוּ.\nאָנָּא שׁוּב מֵחֲרוֹנְךָ וְרַחֵם סְגֻלָּה אֲשֶׁר בָּחַרְתָּ.\nיהוה אֱלֹהֵי יִשְׂרָאֵל, שׁוּב מֵחֲרוֹן אַפֶּךָ וְהִנָּחֵם עַל הָרָעָה לְעַמֶּךָ:\n\nחוּסָה יהוה עָלֵינוּ בְּרַחֲמֶיךָ וְאַל תִּתְּנֵנוּ בִּידֵי אַכְזָרִים. לָמָּה יֹאמְרוּ הַגּוֹיִם \"אַיֵּה נָא אֱלֹהֵיהֶם\"? לְמַעַנְךָ עֲשֵׂה עִמָּנוּ חֶסֶד וְאַל תְּאַחַר.\nאָנָּא שׁוּב מֵחֲרוֹנְךָ וְרַחֵם סְגֻלָּה אֲשֶׁר בָּחַרְתָּ.\nיהוה אֱלֹהֵי יִשְׂרָאֵל, שׁוּב מֵחֲרוֹן אַפֶּךָ וְהִנָּחֵם עַל הָרָעָה לְעַמֶּךָ:\n\nקוֹלֵנוּ תִשְׁמַע וְתָחֹן, וְאַל תִּטְּשֵׁנוּ בְּיַד אֹיְבֵינוּ לִמְחוֹת אֶת שְׁמֵנוּ. זְכֹר אֲשֶׁר נִשְׁבַּעְתָּ לַאֲבוֹתֵינוּ \"כְּכוֹכְבֵי הַשָּׁמַיִם אַרְבֶּה אֶת זַרְעֲכֶם\", וְעַתָּה נִשְׁאַרְנוּ מְעַט מֵהַרְבֵּה.\nוּבְכָל זֹאת שִׁמְךָ לֹא שָׁכָחְנוּ, נָא אַל תִּשְׁכָּחֵנוּ.\nיהוה אֱלֹהֵי יִשְׂרָאֵל, שׁוּב מֵחֲרוֹן אַפֶּךָ וְהִנָּחֵם עַל הָרָעָה לְעַמֶּךָ:\n\nעָזְרֵנוּ אֱלֹהֵי יִשְׁעֵנוּ עַל דְּבַר כְּבוֹד שְׁמֶךָ, וְהַצִּילֵנוּ וְכַפֵּר עַל חַטֹּאתֵינוּ לְמַעַן שְׁמֶךָ:\nיהוה אֱלֹהֵי יִשְׂרָאֵל, שׁוּב מֵחֲרוֹן אַפֶּךָ וְהִנָּחֵם עַל הָרָעָה לְעַמֶּךָ:","cond":["shacharitTachanun","monThu"]},{"kind":"instruction","text":"שומר ישראל","cond":["shacharitTachanun"]},{"kind":"text","text":"שׁוֹמֵר יִשְׂרָאֵל, שְׁמֹר שְׁאֵרִית יִשְׂרָאֵל, וְאַל יֹאבַד יִשְׂרָאֵל, הָאוֹמְרִים שְׁמַע יִשְׂרָאֵל.\nשׁוֹמֵר גּוֹי אֶחָד, שְׁמֹר שְׁאֵרִית עַם אֶחָד, וְאַל יֹאבַד גּוֹי אֶחָד, הַמְיַחֲדִים שִׁמְךָ יהוה אֱלֹהֵינוּ יהוה אֶחָד.\nשׁוֹמֵר גּוֹי קָדוֹשׁ, שְׁמֹר שְׁאֵרִית עַם קָדוֹשׁ, וְאַל יֹאבַד גּוֹי קָדוֹשׁ, הַמְשַׁלְּשִׁים בְּשָׁלֹשׁ קְדֻשּׁוֹת לְקָדוֹשׁ.\n\nמִתְרַצֶּה בְּרַחֲמִים וּמִתְפַּיֵּס בְּתַחֲנוּנִים, הִתְרַצֶּה וְהִתְפַּיֵּס לְדוֹר עָנִי. כִּי אֵין עוֹזֵר.\nאָבִינוּ מַלְכֵּנוּ. חָנֵּנוּ וַעֲנֵנוּ, כִּי אֵין בָּנוּ מַעֲשִׂים, עֲשֵׂה עִמָּנוּ צְדָקָה וָחֶסֶד וְהוֹשִׁיעֵנוּ.\n\nוַאֲנַחְנוּ לֹא נֵדַע מַה נַּעֲשֶׂה, כִּי עָלֶיךָ עֵינֵינוּ: זְכֹר רַחֲמֶיךָ יהוה וַחֲסָדֶיךָ, כִּי מֵעוֹלָם הֵמָּה: יְהִי חַסְדְּךָ יהוה עָלֵינוּ, כַּאֲשֶׁר יִחַלְנוּ לָךְ: אַל תִּזְכָּר לָנוּ עֲוׂנוֹת רִאשׁוֹנִים, מַהֵר יְקַדְּמוּנוּ רַחֲמֶיךָ, כִּי דַלּוֹנוּ מְאֹד: עֶזְרֵנוּ בְּשֵׁם יהוה, עֹשֶׂה שָׁמַיִם וָאָרֶץ: חָנֵּנוּ יהוה חָנֵּנוּ, כִּי רַב שָׂבַעְנוּ בוּז: בְּרֹגֶז רַחֵם תִּזְכּוֹר: בְּרֹגֶז עֲקֵדָה תִזְכֹּר, בְּרֹגֶז תְּמִימוּת תִזְכֹּר. יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְּיוֹם קָרְאֵנוּ: כִּי הוּא יָדַע יִצְרֵנוּ, זָכוּר כִּי עָפָר אֲנָחְנוּ: עָזְרֵנוּ אֱלֹהֵי יִשְׁעֵנוּ עַל דְּבַר כְּבוֹד שְׁמֶךָ, וְהַצִּילֵנוּ וְכַפֵּר עַל חַטֹּאתֵינוּ לְמַעַן שְׁמֶךָ:","cond":["shacharitTachanun"]},{"kind":"instruction","text":"חצי קדיש","cond":["noMusaf"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":["noMusaf"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noMusaf","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noMusaf","ayt"]},{"kind":"header","text":"שיר של יום","cond":["musaf"]},{"kind":"instruction","text":"שיר של יום","cond":["musaf"]},{"kind":"text","text":"תְּפִלָּה לְדָוִד, הַטֵּה יהוה אָזְנְךָ עֲנֵנִי, כִּי עָנִי וְאֶבְיוֹן אָנִי: שָׁמְרָה נַפְשִׁי כִּי חָסִיד אָנִי, הוֹשַׁע עַבְדְּךָ, אַתָּה אֱלֹהַי, הַבּוֹטֵחַ אֵלֶיךָ: חָנֵּנִי אֲדֹנָי, כִּי אֵלֶיךָ אֶקְרָא כָּל הַיּוֹם: שַׂמֵּחַ נֶפֶשׁ עַבְדֶּךָ, כִּי אֵלֶיךָ אֲדֹנָי נַפְשִׁי אֶשָּׂא: כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ: הַאֲזִינָה יהוה תְּפִלָּתִי וְהַקְשִׁיבָה בְּקוֹל תַּחֲנוּנוֹתָי: בְּיוֹם צָרָתִי אֶקְרָאֶךָּ כִּי תַעֲנֵנִי: אֵין כָּמוֹךָ בָאֱלֹהִים, אֲדֹנָי, וְאֵין כְּמַעֲשֶׂיךָ: כָּל גּוֹיִם אֲשֶׁר עָשִׂיתָ יָבוֹאוּ וְיִשְׁתַּחֲווּ לְפָנֶיךָ, אֲדֹנָי, וִיכַבְּדוּ לִשְׁמֶךָ: כִּי גָדוֹל אַתָּה וְעֹשֵׂה נִפְלָאוֹת, אַתָּה אֱלֹהִים לְבַדֶּךָ: הוֹרֵנִי יהוה דַּרְכֶּךָ, אֲהַלֵּךְ בַּאֲמִתֶּךָ, יַחֵד לְבָבִי לְיִרְאָה שְׁמֶךָ: אוֹדְךָ אֲדֹנָי אֱלֹהַי בְּכָל לְבָבִי, וַאֲכַבְּדָה שִׁמְךָ לְעוֹלָם: כִּי חַסְדְּךָ גָּדוֹל עָלָי, וְהִצַּלְתָּ נַפְשִׁי מִשְּׁאוֹל תַּחְתִּיָּה: אֱלֹהִים, זֵדִים קָמוּ עָלַי, וַעֲדַת עָרִיצִים בִּקְשׁוּ נַפְשִׁי, וְלֹא שָׂמוּךָ לְנֶגְדָּם: וְאַתָּה אֲדֹנָי אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב חֶסֶד וֶאֱמֶת: פְּנֵה אֵלַי וְחָנֵּנִי, תְּנָה עֻזְּךָ לְעַבְדֶּךָ, וְהוֹשִׁיעָה לְבֶן אֲמָתֶךָ: עֲשֵׂה עִמִּי אוֹת לְטוֹבָה, וְיִרְאוּ שֹׂנְאַי וְיֵבֹשׁוּ, כִּי אַתָּה יהוה עֲזַרְתַּנִי וְנִחַמְתָּנִי:","cond":["musaf","shacharitTachanun"]},{"kind":"text","text":"בֵּית יַעֲקֹב, לְכוּ וְנֵלְכָה בְּאוֹר יהוה: כִּי כָּל הָעַמִּים יֵלְכוּ אִישׁ בְּשֵׁם אֱלֹהָיו, וַאֲנַחְנוּ נֵלֵךְ בְּשֵׁם יהוה אֱלֹהֵינוּ לְעוֹלָם וָעֶד: יְהִי יהוה אֱלֹהֵינוּ עִמָּנוּ כַּאֲשֶׁר הָיָה עִם אבוֹתֵינוּ, אַל יַעַזְבֵנוּ וְאַל יִטְּשֵׁנוּ: לְהַטּות לְבָבֵנוּ אֵלָיו, לָלֶכֶת בְּכָל דְּרָכָיו וְלִשְׁמֹר מִצְוׂתָיו וְחֻקָּיו וּמִשְׁפָּטָיו אֲשֶׁר צִוָּה אֶת אֲבֹתֵינוּ: וְיִהְיוּ דְבָרַי אֵלֶּה אֲשֶׁר הִתְחַנַּנְתִּי לִפְנֵי יהוה קְרֹבִים אֶל יהוה אֱלֹהֵינוּ יוֹמָם וָלָיְלָה, לַעֲשׂוֹת מִשְׁפַּט עַבְדּוֹ וּמִשְׁפַּט עַמּוֹ יִשְׂרָאֵל דְּבַר יוֹם בְּיוֹמוֹ: לְמַעַן דַּעַת כָּל עַמֵּי הָאָרֶץ כִּי יהוה הוּא הָאֱלֹהִים, אֵין עוד:\n\nשִׁיר הַמַּעֲלוֹת לְדָוִד, לוּלֵי יהוה שֶׁהָיָה לָנוּ יֹאמַר נָא יִשְׂרָאֵל: לוּלֵי יהוה שֶׁהָיָה לָנוּ בְּקוּם עָלֵינוּ אָדָם: אֲזַי חַיִּים בְּלָעוּנוּ בַּחֲרוֹת אַפָּם בָּנוּ: אֲזַי הַמַּיִם שְׁטָפוּנוּ נַחְלָה עָבַר עַל נַפְשֵׁנוּ: אֲזַי עָבַר עַל נַפְשֵׁנוּ הַמַּיִם הַזֵּידוֹנִים: בָּרוּךְ יהוה שֶׁלֹּא נְתָנָנוּ טֶרֶף לְשִׁנֵּיהֶם: נַפְשֵׁנוּ כְּצִפּוֹר נִמְלְטָה מִפַּח יוֹקְשִׁים, הַפַּח נִשְׁבָּר וַאֲנַחְנוּ נִמְלָטְנוּ: עֶזְרֵנוּ בְּשֵׁם יהוה, עֹשֵׂה שָׁמַיִם וָאָרֶץ:","cond":["musaf","lamnatzeach"]},{"kind":"text","text":"הַיּוֹם יוֹם רִאשׁוֹן בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["musaf","sun"]},{"kind":"text","text":"לְדָוִד מִזְמוֹר, לַיהוה הָאָרֶץ וּמְלוֹאָהּ, תֵּבֵל וְיֹשְׁבֵי בָהּ: כִּי הוּא עַל יַמִּים יְסָדָהּ, וְעַל נְהָרוֹת יְכוֹנְנֶהָ: מִי יַעֲלֶה בְהַר יהוה, וּמִי יָקוּם בִּמְקוֹם קָדְשׁוֹ: נְקִי כַפַּיִם וּבַר לֵבָב, אֲשֶׁר לֹא נָשָׂא לַשָּׁוְא נַפְשִׁי וְלֹא נִשְׁבַּע לְמִרְמָה: יִשָּׂא בְרָכָה מֵאֵת יהוה, וּצְדָקָה מֵאֱלֹהֵי יִשְׁעוֹ: זֶה דּוֹר דֹּרְשָׁיו, מְבַקְשֵׁי פָנֶיךָ יַעֲקֹב סֶלָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וְהִנָּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבוֹא מֶלֶךְ הַכָּבוֹד: מִי זֶה מֶלֶךְ הַכָּבוֹד, יהוה עִזּוּז וְגִבּוֹר, יהוה גִּבּוֹר מִלְחָמָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבֹא מֶלֶךְ הַכָּבוֹד: מִי הוּא זֶה מֶלֶךְ הַכָּבוֹד, יהוה צְבָאוֹת הוּא מֶלֶךְ הַכָּבוֹד סֶלָה:","cond":["musaf","sun"]},{"kind":"text","text":"הַיּוֹם יוֹם שֵׁנִי בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["musaf","mon"]},{"kind":"text","text":"שִׁיר מִזְמוֹר לִבְנֵי קֹרַח: גָּדוֹל יהוה וּמְהֻלָּל מְאֹד בְּעִיר אֱלֹהֵינוּ הַר קָדְשׁוֹ: יְפֵה נוֹף, מְשׂוֹשׂ כָּל הָאָרֶץ, הַר צִיּוֹן יַרְכְּתֵי צָפוֹן קִרְיַת מֶלֶךְ רָב: אֱלֹהִים בְּאַרְמְנוֹתֶיהָ נוֹדַע לְמִשְׂגָּב: כִּי הִנֵּה הַמְּלָכִים נוֹעֲדוּ עָבְרוּ יַחְדָּו: הֵמָּה רָאוּ כֵּן תָּמָהוּ, נִבְהֲלוּ נֶחְפָּזוּ: רְעָדָה אֲחָזָתַם שָׁם, חִיל כַּיּוֹלֵדָה: בְּרוּחַ קָדִים תְּשַׁבֵּר אֳנִיּוֹת תַּרְשִׁישׁ: כַּאֲשֶׁר שָׁמַעְנוּ כֵּן רָאִינוּ בְּעִיר יהוה צְבָאוֹת בְּעִיר אֱלֹהֵינוּ, אֱלֹהִים יְכוֹנְנֶהָ עַד עוֹלָם סֶלָה: דִּמִּינוּ אֱלֹהִים חַסְדֶּךָ בְּקֶרֶב הֵיכָלֶךָ: כְּשִׁמְךָ אֱלֹהִים כֵּן תְּהִלָּתְךָ עַל קַצְוֵי אֶרֶץ, צֶדֶק מָלְאָה יְמִינֶךָ: יִשְׂמַח הַר צִיּוֹן, תָּגֵלְנָה בְּנוֹת יְהוּדָה, לְמַעַן מִשְׁפָּטֶיךָ: סֹבּוּ צִיּוֹן וְהַקִּיפוּהָ, סִפְרוּ מִגְדָּלֶיהָ: שִׁיתוּ לִבְּכֶם לְחֵילָה, פַּסְּגוּ אַרְמְנוֹתֶיהָ, לְמַעַן תְּסַפְּרוּ לְדוֹר אַחֲרוֹן: כִּי זֶה אֱלֹהִים אֱלֹהֵינוּ עוֹלָם וָעֶד, הוּא יְנַהֲגֵנוּ עַל מוּת:","cond":["musaf","mon"]},{"kind":"text","text":"הַיּוֹם יוֹם שְׁלִישִׁי בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["musaf","tue"]},{"kind":"text","text":"מִזְמוֹר לְאָסָף, אֱלֹהִים נִצָּב בַּעֲדַת אֵל, בְּקֶרֶב אֱלֹהִים יִשְׁפֹּט: עַד מָתַי תִּשְׁפְּטוּ עָוֶל וּפְנֵי רְשָׁעִים תִּשְׂאוּ סֶלָה: שִׁפְטוּ דַל וְיָתוֹם, עָנִי וָרָשׁ הַצְדִּיקוּ: פַּלְּטוּ דַל וְאֶבְיוֹן, מִיַּד רְשָׁעִים הַצִּילוּ: לֹא יָדְעוּ וְלֹא יָבִינוּ, בַּחֲשֵׁכָה יִתְהַלָּכוּ, יִמּוֹטוּ כָּל מוֹסְדֵי אָרֶץ: אֲנִי אָמַרְתִּי אֱלֹהִים אַתֶּם וּבְנֵי עֶלְיוֹן כֻּלְּכֶם: אָכֵן כְּאָדָם תְּמוּתוּן וּכְאַחַד הַשָּׂרִים תִּפֹּלוּ: קוּמָה אֱלֹהִים שָׁפְטָה הָאָרֶץ, כִּי אַתָּה תִנְחַל בְּכָל הַגּוֹיִם:","cond":["musaf","tue"]},{"kind":"text","text":"הַיּוֹם יוֹם רְבִיעִי בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["musaf","wed"]},{"kind":"text","text":"אֵל נְקָמוֹת יהוה, אֵל נְקָמוֹת הוֹפִיעַ: הִנָּשֵׂא שֹׁפֵט הָאָרֶץ, הָשֵׁב גְּמוּל עַל גֵּאִים: עַד מָתַי רְשָׁעִים, יהוה, עַד מָתַי רְשָׁעִים יַעֲלֹזוּ: יַבִּיעוּ יְדַבְּרוּ עָתָק, יִתְאַמְּרוּ כָּל פֹעֲלֵי אָוֶן: עַמְּךָ יהוה יְדַכְּאוּ, וְנַחֲלָתְךָ יְעַנּוּ: אַלְמָנָה וְגֵר יַהֲרֹגוּ, וִיתוֹמִים יְרַצֵּחוּ: וַיֹּאמְרוּ לֹא יִרְאֶה יָהּ, וְלֹא יָבִין אֱלֹהֵי יַעֲקֹב: בִּינוּ בֹּעֲרִים בָּעָם, וּכְסִילִים מָתַי תַּשְׂכִּילוּ: הַנֹּטַע אֹזֶן הֲלֹא יִשְׁמָע, אִם יֹצֵר עַיִן הֲלֹא יַבִּיט: הֲיֹסֵר גּוֹיִם הֲלֹא יוֹכִיחַ, הַמְלַמֵּד אָדָם דָּעַת: יהוה יֹדֵעַ מַחְשְׁבוֹת אָדָם כִּי הֵמָּה הָבֶל: אַשְׁרֵי הַגֶּבֶר אֲשֶׁר תְּיַסְּרֶנּוּ יָּהּ, וּמִתּוֹרָתְךָ תְלַמְּדֶנּוּ: לְהַשְׁקִיט לוֹ מִימֵי רָע, עַד יִכָּרֶה לָרָשָׁע שָׁחַת: כִּי לֹא יִטֹּשׁ יהוה עַמּוֹ, וְנַחֲלָתוֹ לֹא יַעֲזֹב: כִּי עַד צֶדֶק יָשׁוּב מִשְׁפָּט, וְאַחֲרָיו כָּל יִשְׁרֵי לֵב: מִי יָקוּם לִי עִם מְרֵעִים, מִי יִתְיַצֵּב לִי עִם פֹּעֲלֵי אָוֶן: לוּלֵי יהוה עֶזְרָתָה לִּי, כִּמְעַט שָׁכְנָה דוּמָה נַפְשִׁי: אִם אָמַרְתִּי מָטָה רַגְלִי, חַסְדְּךָ יהוה יִסְעָדֵנִי: בְּרֹב שַׂרְעַפַּי בְּקִרְבִּי, תַּנְחוּמֶיךָ יְשַׁעַשְׁעוּ נַפְשִׁי: הַיְחָבְרְךָ כִּסֵּא הַוּוֹת, יֹצֵר עָמָל עֲלֵי חֹק: יָגוֹדּוּ עַל נֶפֶשׁ צַדִּיק, וְדָם נָקִי יַרְשִׁיעוּ: וַיְהִי יהוה לִי לְמִשְׂגָּב, וֵאלֹהַי לְצוּר מַחְסִי: וַיָּשֶׁב עֲלֵיהֶם אֶת אוֹנָם וּבְרָעָתָם יַצְמִיתֵם, יַצְמִיתֵם יהוה אֱלֹהֵינוּ:\nלְכוּ נְרַנְּנָה לַיהוה, נָרִיעָה לְצוּר יִשְׁעֵנוּ: נְקַדְּמָה פָנָיו בְּתוֹדָה, בִּזְמִרוֹת נָרִיעַ לוֹ: כִּי אֵל גָּדוֹל יהוה, וּמֶלֶךְ גָּדוֹל עַל כָּל אֱלֹהִים:","cond":["musaf","wed"]},{"kind":"text","text":"הַיּוֹם יוֹם חֲמִישִׁי בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["musaf","thu"]},{"kind":"text","text":"לַמְנַצֵּחַ עַל הַגִּתִּית לְאָסָף: הַרְנִינוּ לֵאלֹהִים עֻזֵּנוּ, הָרִיעוּ לֵאלֹהֵי יַעֲקֹב: שְׂאוּ זִמְרָה וּתְנוּ תֹף, כִּנּוֹר נָעִים עִם נָבֶל: תִּקְעוּ בַחֹדֶשׁ שׁוֹפָר, בַּכֵּסֶה לְיוֹם חַגֵּנוּ: כִּי חֹק לְיִשְׂרָאֵל הוּא, מִשְׁפָּט לֵאלֹהֵי יַעֲקֹב: עֵדוּת בִּיהוֹסֵף שָׂמוֹ בְּצֵאתוֹ עַל אֶרֶץ מִצְרָיִם, שְׂפַת לֹא יָדַעְתִּי אֶשְׁמָע: הֲסִירוֹתִי מִסֵּבֶל שִׁכְמוֹ, כַּפָּיו מִדּוּד תַּעֲבֹרְנָה: בַּצָּרָה קָרָאתָ וָאֲחַלְּצֶךָּ, אֶעֶנְךָ בְּסֵתֶר רַעַם, אֶבְחָנְךָ עַל מֵי מְרִיבָה סֶלָה: שְׁמַע עַמִּי וְאָעִידָה בָּךְ, יִשְׂרָאֵל אִם תִּשְׁמַע לִי: לֹא יִהְיֶה בְךָ אֵל זָר, וְלֹא תִשְׁתַּחֲוֶה לְאֵל נֵכָר: אָנֹכִי יהוה אֱלֹהֶיךָ הַמַּעַלְךָ מֵאֶרֶץ מִצְרָיִם, הַרְחֶב פִּיךָ וַאֲמַלְאֵהוּ: וְלֹא שָׁמַע עַמִּי לְקוֹלִי, וְיִשְׂרָאֵל לֹא אָבָה לִי: וָאֲשַׁלְּחֵהוּ בִּשְׁרִירוּת לִבָּם, יֵלְכוּ בְּמוֹעֲצוֹתֵיהֶם: לוּ עַמִּי שֹׁמֵעַ לִי, יִשְׂרָאֵל בִּדְרָכַי יְהַלֵּכוּ: כִּמְעַט אוֹיְבֵיהֶם אַכְנִיעַ, וְעַל צָרֵיהֶם אָשִׁיב יָדִי: מְשַׂנְאֵי יהוה יְכַחֲשׁוּ לוֹ, וִיהִי עִתָּם לְעוֹלָם: וַיַּאֲכִילֵהוּ מֵחֵלֶב חִטָּה, וּמִצּוּר, דְּבַשׁ אַשְׂבִּיעֶךָ:","cond":["musaf","thu"]},{"kind":"text","text":"הַיּוֹם יוֹם שִׁשִּׁי בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["musaf","fri"]},{"kind":"text","text":"יהוה מָלָךְ גֵּאוּת לָבֵשׁ, לָבֵשׁ יהוה עֹז הִתְאַזָּר, אַף תִּכּוֹן תֵּבֵל בַּל תִּמּוֹט: נָכוֹן כִּסְאֲךָ מֵאָז, מֵעוֹלָם אָתָּה: נָשְׂאוּ נְהָרוֹת, יהוה, נָשְׂאוּ נְהָרוֹת קוֹלָם, יִשְׂאוּ נְהָרוֹת דָכְיָם: מִקֹּלוֹת מַיִם רַבִּים, אַדִּירִים מִשְׁבְּרֵי יָם, אַדִּיר בַּמָּרוֹם יהוה: עֵדֹתֶיךָ נֶאֶמְנוּ מְאֹד לְבֵיתְךָ נַאֲוָה קֹדֶשׁ, יהוה, לְאֹרֶךְ יָמִים:","cond":["musaf","fri"]},{"kind":"special","text":"בָּרְכִי נַפְשִׁי אֶת יהוה, יהוה אֱלֹהַי גָּדַלְתָּ מְּאֹד, הוֹד וְהָדָר לָבָשְׁתָּ:\nעֹטֶה אוֹר כַּשַּׂלְמָה נוֹטֶה שָׁמַיִם כַּיְרִיעָה:\nהַמְקָרֶה בַמַּיִם עֲלִיּוֹתָיו, הַשָּׂם עָבִים רְכוּבוֹ, הַמְהַלֵּךְ עַל כַּנְפֵי רוּחַ:\nעֹשֶׂה מַלְאָכָיו רוּחוֹת, מְשָׁרְתָיו אֵשׁ לֹהֵט:\nיָסַד אֶרֶץ עַל מְכוֹנֶיהָ, בַּל תִּמּוֹט עוֹלָם וָעֶד:\nתְּהוֹם כַּלְּבוּשׁ כִּסִּיתוֹ, עַל הָרִים יַעַמְדוּ מָיִם:\nמִן גַּעֲרָתְךָ יְנוּסוּן, מִן קוֹל רַעַמְךָ יֵחָפֵזוּן:\nיַעֲלוּ הָרִים, יֵרְדוּ בְקָעוֹת, אֶל מְקוֹם זֶה יָסַדְתָּ לָהֶם:\nגְּבוּל שַׂמְתָּ בַּל יַעֲבֹרוּן, בַּל יְשׁוּבוּן לְכַסּוֹת הָאָרֶץ:\nהַמְשַׁלֵּחַ מַעְיָנִים בַּנְּחָלִים בֵּין הָרִים יְהַלֵּכוּן:","cond":["musaf","rh"]},{"kind":"special","text":"יַשְׁקוּ כָּל חַיְתוֹ שָׂדָי, יִשְׁבְּרוּ פְרָאִים צְמָאָם:\nעֲלֵיהֶם עוֹף הַשָּׁמַיִם יִשְׁכּוֹן, מִבֵּין עֳפָאיִם יִתְּנוּ קוֹל:\nמַשְׁקֶה הָרִים מֵעֲלִיּוֹתָיו, מִפְּרִי מַעֲשֶׂיךָ תִּשְׂבַּע הָאָרֶץ:\nמַצְמִיחַ חָצִיר לַבְּהֵמָה וְעֵשֶׂב לַעֲבֹדַת הָאָדָם, לְהוֹצִיא לֶחֶם מִן הָאָרֶץ:\nוְיַיִן יְשַׂמַּח לְבַב אֱנוֹשׁ, לְהַצְהִיל פָּנִים מִשָּׁמֶן, וְלֶחֶם לְבַב אֱנוֹשׁ יִסְעָד:\nיִשְׂבְּעוּ עֲצֵי יהוה, אַרְזֵי לְבָנוֹן אֲשֶׁר נָטָע:\nאֲשֶׁר שָׁם צִפֳּרִים יְקַנֵּנוּ, חֲסִידָה בְּרוֹשִׁים בֵּיתָהּ:\nהָרִים הַגְּבֹהִים לַיְּעֵלִים, סְלָעִים מַחְסֶה לַשְׁפַנִּים:\nעָשָׂה יָרֵחַ לְמוֹעֲדִים, שֶׁמֶשׁ יָדַע מְבוֹאוֹ:\nתָּשֶׁת חֹשֶׁךְ וִיהִי לָיְלָה, בּוֹ תִרְמֹשׂ כָּל חַיְתוֹ יָעַר:\nהַכְּפִירִים שֹׁאֲגִים לַטָּרֶף וּלְבַקֵּשׁ מֵאֵל אָכְלָם:\nתִּזְרַח הַשֶּׁמֶשׁ יֵאָסֵפוּן וְאֶל מְעוֹנֹתָם יִרְבָּצוּן:","cond":["musaf","rh"]},{"kind":"special","text":"יֵצֵא אָדָם לְפָעֳלוֹ וְלַעֲבֹדָתוֹ עֲדֵי עָרֶב:\nמָה רַבּוּ מַעֲשֶׂיךָ יהוה, כֻּלָּם בְּחָכְמָה עָשִׂיתָ, מָלְאָה הָאָרֶץ קִנְיָנֶךָ:\nזֶה הַיָּם גָּדוֹל וּרְחַב יָדָיִם, שָׁם רֶמֶשׂ וְאֵין מִסְפָּר, חַיּוֹת קְטַנּוֹת עִם גְּדֹלוֹת:\nשָׁם אֳנִיּוֹת יְהַלֵּכוּן, לִוְיָתָן זֶה יָצַרְתָּ לְשַׂחֶק בּוֹ:\nכֻּלָּם אֵלֶיךָ יְשַׂבֵּרוּן לָתֵת אָכְלָם בְּעִתּוֹ:\nתִּתֵּן לָהֶם יִלְקֹטוּן, תִּפְתַּח יָדְךָ יִשְׂבְּעוּן טוֹב:\nתַּסְתִּיר פָּנֶיךָ יִבָּהֵלוּן, תֹּסֵף רוּחָם יִגְוָעוּן וְאֶל עֲפָרָם יְשׁוּבוּן:\nתְּשַׁלַּח רוּחֲךָ יִבָּרֵאוּן וּתְחַדֵּשׁ פְּנֵי אֲדָמָה:\nיְהִי כְבוֹד יהוה לְעוֹלָם, יִשְׂמַח יהוה בְּמַעֲשָׂיו:\nהַמַּבִּיט לָאָרֶץ וַתִּרְעָד, יִגַּע בֶּהָרִים וְיֶעֱשָׁנוּ:\nאָשִׁירָה לַיהוה בְּחַיָּי, אֲזַמְּרָה לֵאלֹהַי בְּעוֹדִי:\nיֶעֱרַב עָלָיו שִׂיחִי, אָנֹכִי אֶשְׂמַח בַּיהוה:\nיִתַּמּוּ חַטָּאִים מִן הָאָרֶץ וּרְשָׁעִים עוֹד אֵינָם, בָּרְכִי נַפְשִׁי אֶת יהוה, הַלְלוּיָהּ:","cond":["musaf","rh"]},{"kind":"header","text":"הושיענו","cond":["musaf"]},{"kind":"instruction","text":"בכל יום אחרי שיר של יום אומרים:","cond":["musaf"]},{"kind":"text","text":"הוֹשִׁיעֵנוּ יהוה אֱלֹהֵינוּ וְקַבְּצֵנוּ מִן הַגּוֹיִם, לְהֹדוֹת לְשֵׁם קָדְשֶׁךָ לְהִשְׁתַּבֵּחַ בִּתְהִלָּתֶךָ: בָּרוּךְ יהוה אֱלֹהֵי יִשְׂרָאֵל מִן הָעוֹלָם וְעַד הָעוֹלָם, וְאָמַר כָּל הָעָם אָמֵן הַלְלוּיָהּ: בָּרוּךְ יהוה מִצִּיּוֹן, שֹׁכֵן יְרוּשָׁלִָם הַלְלוּיָהּ: בָּרוּךְ יהוה אֱלֹהִים אֱלֹהֵי יִשְׂרָאֵל, עֹשֵׂה נִפְלָאוֹת לְבַדּוֹ: וּבָרוּךְ שֵׁם כְּבוֹדוֹ לְעוֹלָם, וְיִמָּלֵא כְבוֹדוֹ אֶת כָּל הָאָרֶץ, אָמֵן וְאָמֵן:","cond":["musaf"]},{"kind":"instruction","text":"קדיש יתום","cond":["musaf"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":["musaf"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["musaf","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["musaf","ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":["musaf"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["musaf","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["musaf","ayt"]},{"kind":"header","text":"מזמור לבית האבל","cond":["musaf"]},{"kind":"instruction","text":"בבית האבל אומרים מזמור זה:","cond":["musaf","shacharitTachanun"]},{"kind":"text","text":"לַמְנַצֵּחַ לִבְנֵי קֹרַח מִזְמוֹר: שִׁמְעוּ זֹאת כָּל הָעַמִּים, הַאֲזִינוּ כָּל יֹשְׁבֵי חָלֶד: גַּם בְּנֵי אָדָם, גַּם בְּנֵי אִישׁ, יַחַד עָשִׁיר וְאֶבְיוֹן: פִּי יְדַבֵּר חָכְמוֹת, וְהָגוּת לִבִּי תְבוּנוֹת: אַטֶּה לְמָשָׁל אָזְנִי, אֶפְתַּח בְּכִנּוֹר חִידָתִי: לָמָּה אִירָא בִּימֵי רָע, עֲוׂן עֲקֵבַי יְסוּבֵּנִי: הַבֹּטְחִים עַל חֵילָם, וּבְרֹב עָשְׁרָם יִתְהַלָּלוּ: אָח לֹא פָדֹה יִפְדֶּה אִישׁ, לֹא יִתֵּן לֵאלֹהִים כָּפְרוֹ: וְיֵקַר פִּדְיוֹן נַפְשָׁם, וְחָדַל לְעוֹלָם: וִיחִי עוֹד לָנֶצַח, לֹא יִרְאֶה הַשָּׁחַת: כִּי יִרְאֶה חֲכָמִים יָמוּתוּ, יַחַד כְּסִיל וָבַעַר יֹאבֵדוּ, וְעָזְבוּ לַאֲחֵרִים חֵילָם: קִרְבָּם בָּתֵּימוֹ לְעוֹלָם, מִשְׁכְּנֹתָם לְדֹר וָדֹר, קָרְאוּ בִשְׁמוֹתָם עֲלֵי אֲדָמוֹת: וְאָדָם בִּיקָר בַּל יָלִין, נִמְשַׁל כַּבְּהֵמוֹת נִדְמוּ: זֶה דַרְכָּם כֵּסֶל לָמוֹ, וְאַחֲרֵיהֶם בְּפִיהֶם יִרְצוּ סֶלָה: כַּצֹּאן לִשְׁאוֹל שַׁתּוּ מָוֶת יִרְעֵם, וַיִּרְדּוּ בָם יְשָׁרִים לַבֹּקֶר, וְצוּרָם לְבַלּוֹת שְׁאוֹל מִזְּבֻל לוֹ: אַךְ אֱלֹהִים יִפְדֶּה נַפְשִׁי מִיַּד שְׁאוֹל, כִּי יִקָּחֵנִי סֶלָה: אַל תִּירָא כִּי יַעֲשִׁר אִישׁ, כִּי יִרְבֶּה כְּבוֹד בֵּיתוֹ: כִּי לֹא בְמוֹתוֹ יִקַּח הַכֹּל, לֹא יֵרֵד אַחֲרָיו כְּבוֹדוֹ: כִּי נַפְשׁוֹ בְּחַיָּיו יְבָרֵךְ, וְיוֹדֻךָ כִּי תֵיטִיב לָךְ: תָּבוֹא עַד דּוֹר אֲבוֹתָיו, עַד נֵצַח לֹא יִרְאוּ אוֹר: אָדָם בִּיקָר וְלֹא יָבִין נִמְשַׁל כַּבְּהֵמוֹת נִדְמוּ:","cond":["musaf","shacharitTachanun"]},{"kind":"instruction","text":"בבית האבל אומרים מזמור זה:","cond":["musaf","noShacharitTachanun"]},{"kind":"text","text":"מִכְתָּם לְדָוִד, שָׁמְרֵנִי אֵל כִּי חָסִיתִי בָךְ: אָמַרְתְּ לַיהוה, אֲדֹנָי אָתָּה, טוֹבָתִי בַּל עָלֶיךָ: לִקְדוֹשִׁים אֲשֶׁר בָּאָרֶץ הֵמָּה, וְאַדִּירֵי כָּל חֶפְצִי בָם: יִרְבּוּ עַצְּבוֹתָם אַחֵר מָהָרוּ, בַּל אַסִּיךְ נִסְכֵּיהֶם מִדָּם, וּבַל אֶשָּׂא אֶת שְׁמוֹתָם עַל שְׂפָתָי: יהוה, מְנָת חֶלְקִי וְכוֹסִי, אַתָּה תּוֹמִיךְ גּוֹרָלִי: חֲבָלִים נָפְלוּ לִי בַּנְּעִמִים, אַף נַחֲלָת שָׁפְרָה עָלָי: אֲבָרֵךְ אֶת יהוה אֲשֶׁר יְעָצָנִי, אַף לֵילוֹת יִסְּרוּנִי כִלְיוֹתָי: שִׁוִּיתִי יהוה לְנֶגְדִּי תָמִיד, כִּי מִימִינִי בַּל אֶמּוֹט: לָכֵן שָׂמַח לִבִּי וַיָּגֶל כְּבוֹדִי, אַף בְּשָׂרִי יִשְׁכֹּן לָבֶטַח: כִּי לֹא תַעֲזֹב נַפְשִׁי לִשְׁאוֹל, לֹא תִתֵּן חֲסִידְךָ לִרְאוֹת שָׁחַת: תּוֹדִיעֵנִי אֹרַח חַיִּים, שֹׂבַע שְׂמָחוֹת אֶת פָּנֶיךָ, נְעִמוֹת בִּימִינְךָ נֶצַח:","cond":["musaf","noShacharitTachanun"]},{"kind":"instruction","text":"קדיש יתום","cond":["musaf"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":["musaf"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["musaf","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["musaf","ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":["musaf"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["musaf","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["musaf","ayt"]},{"kind":"header","text":"לדוד","cond":["musaf","ledavid"]},{"kind":"special","text":"לְדָוִד, יהוה אוֹרִי וְיִשְׁעִי מִמִּי אִירָא, יהוה מָעוֹז חַיַּי מִמִּי אֶפְחָד: בִּקְרֹב עָלַי מְרֵעִים לֶאֱכֹל אֶת בְּשָׂרִי, צָרַי וְאֹיְבַי לִי, הֵמָּה כָשְׁלוּ וְנָפָלוּ: אִם תַּחֲנֶה עָלַי מַחֲנֶה לֹא יִירָא לִבִּי, אִם תָּקוּם עָלַי מִלְחָמָה בְּזֹאת אֲנִי בוֹטֵחַ: אַחַת שָׁאַלְתִּי מֵאֵת יהוה, אוֹתָהּ אֲבַקֵּשׁ, שִׁבְתִּי בְּבֵית יהוה כָּל יְמֵי חַיַּי, לַחֲזוֹת בְּנֹעַם יהוה וּלְבַקֵּר בְּהֵיכָלוֹ: כִּי יִצְפְּנֵנִי בְּסֻכֹּה בְּיוֹם רָעָה יַסְתִּירֵנִי בְּסֵתֶר אָהֳלוֹ, בְּצוּר יְרוֹמְמֵנִי: וְעַתָּה יָרוּם רֹאשִׁי עַל אֹיְבַי סְבִיבוֹתַי, וְאֶזְבְּחָה בְאָהֳלוֹ זִבְחֵי תְרוּעָה, אָשִׁירָה וַאֲזַמְּרָה לַיהוה: שְׁמַע יהוה קוֹלִי אֶקְרָא, וְחָנֵּנִי וַעֲנֵנִי: לְךָ אָמַר לִבִּי בַּקְּשׁוּ פָנַי, אֶת פָּנֶיךָ יהוה אֲבַקֵּשׁ: אַל תַּסְתֵּר פָּנֶיךָ מִמֶּנִּי, אַל תַּט בְּאַף עַבְדֶּךָ, עֶזְרָתִי הָיִיתָ, אַל תִּטְּשֵׁנִי וְאַל תַּעַזְבֵנִי אֱלֹהֵי יִשְׁעִי: כִּי אָבִי וְאִמִּי עֲזָבוּנִי, וַיהוה יַאַסְפֵנִי: הוֹרֵנִי יהוה דַּרְכֶּךָ וּנְחֵנִי בְּאֹרַח מִישׁוֹר לְמַעַן שׁוֹרְרָי: אַל תִּתְּנֵנִי בְּנֶפֶשׁ צָרָי, כִּי קָמוּ בִי עֵדֵי שֶׁקֶר וִיפֵחַ חָמָס: לוּלֵא הֶאֱמַנְתִּי לִרְאוֹת בְּטוּב יהוה בְּאֶרֶץ חַיִּים: קַוֵּה אֶל יהוה, חֲזַק וְיַאֲמֵץ לִבֶּךָ, וְקַוֵּה אֶל יהוה:","cond":["musaf","ledavid"]},{"kind":"instruction","text":"קדיש יתום","cond":["musaf","ledavid"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":["musaf","ledavid"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["musaf","ledavid","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["musaf","ledavid","ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":["musaf","ledavid"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["musaf","ledavid","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["musaf","ledavid","ayt"]},{"kind":"header","text":"הוצאת ספר תורה","cond":["tora"]},{"kind":"instruction","text":"הוצאת ספר תורה","cond":["tora"]},{"kind":"instruction","text":"נוסח אשכנז:","cond":["tora","lErechApayim"]},{"kind":"text","text":"אֵל אֶרֶךְ אַפַּיִם וְרַב חֶסֶד וֶאֱמֶת, אַל בְּאַפְּךָ תוֹכִיחֵנוּ. חוּסָה יהוה עַל עַמֶּךָ וְהוֹשִׁיעֵנוּ מִכָּל רָע. חָטָאנוּ לְךָ אָדוֹן, סְלַח נָא כְּרֹב רַחֲמֶיךָ אֵל.","cond":["tora","lErechApayim"]},{"kind":"instruction","text":"נוסח פולין:","cond":["tora","lErechApayim"]},{"kind":"text","text":"אֵל אֶרֶךְ אַפַּיִם וּמָלֵא רַחֲמִים, אַל תַּסְתֵּר פָּנֶיךָ מִמֶּנּוּ. חוּסָה יהוה עַל שְׁאֵרִית יִשְׂרָאֵל עַמֶּךָ וְהַצִּילֵנוּ מִכָּל רָע. חָטָאנוּ לְךָ אָדוֹן, סְלַח נָא כְּרֹב רַחֲמֶיךָ אֵל.","cond":["tora","lErechApayim"]},{"kind":"text","text":"וַיְהִי בִּנְסֹעַ הָאָרֹן וַיֹּאמֶר מֹשֶׁה קוּמָה יהוה וְיָפֻצוּ אֹיְבֶיךָ וְיָנֻסוּ מְשַׂנְאֶיךָ מִפָּנֶיךָ: כִּי מִצִּיּוֹן תֵּצֵא תוֹרָה וּדְבַר יהוה מִירוּשָׁלָיִם: בָּרוּךְ שֶׁנָּתַן תּוֹרָה לְעַמּוֹ יִשְׂרָאֵל בִּקְדֻשָּׁתוֹ.\n\nבְּרִיךְ שְׁמֵהּ דְּמָרֵא עָלְמָא. בְּרִיךְ כִּתְרָךְ וְאַתְרָךְ. יְהֵא רְעוּתָךְ עִם עַמָּךְ יִשְׂרָאֵל לְעָלַם. וּפֻרְקַן יְמִינָךְ אַחֲזֵי לְעַמָּךְ בְּבֵית מַקְדְּשָׁךְ. וּלְאַמְטוֹיֵי לָנָא מִטּוּב נְהוֹרָךְ וּלְקַבֵּל צְלוֹתָנָא בְּרַחֲמִין. יְהֵא רַעֲוָא קֳדָמָךְ דְּתוֹרִיךְ לָן חַיִּין בְּטִיבוּ. וְלֶהֱוֵי אֲנָא פְקִידָא בְּגוֹ צַדִּיקַיָּא. לְמִרְחַם עָלַי וּלְמִנְטַר יָתִי וְיַת כָּל דִּי לִי וְדִי לְעַמָּךְ יִשְׂרָאֵל. אַנְתְּ הוּא זָן לְכֹלָּא וּמְפַרְנֵס לְכֹלָּא. אַנְתְּ הוּא שַׁלִּיט עַל כֹּלָּא. אַנְתְּ הוּא דְשַׁלִּיט עַל מַלְכַיָּא. וּמַלְכוּתָא דִּילָךְ הִיא. אֲנָא עַבְדָּא דְקֻדְשָׁא בְּרִיךְ הוּא דְּסָגִידְנָא קַמֵּהּ וּמִקַּמֵּי דִּיקַר אוֹרַיְתֵהּ בְּכָל עִדָּן וְעִדָּן. לָא עַל אֱנָשׁ רָחִיצְנָא וְלָא עַל בַּר אֱלָהִין סָמִיכְנָא. אֶלָּא בֶּאֱלָהָא דִשְׁמַיָּא. דְּהוּא אֱלָהָא קְשׁוֹט וְאוֹרַיְתֵהּ קְשׁוֹט וּנְבִיאוֹהִי קְשׁוֹט. וּמַסְגֵּא לְמֶעְבַּד טַבְוָן וּקְשׁוֹט. בֵּהּ אֲנָא רָחִיץ. וְלִשְׁמֵהּ יַקִּירָא קַדִּישָׁא אֲנָא אֵמַר תֻּשְׁבְּחָן. יְהֵא רַעֲוָא קֳדָמָךְ דְּתִפְתַּח לִבָּאִי בְּאוֹרַיְתָא. וְתַשְׁלִים מִשְׁאֲלִין דְּלִבָּאי וְלִבָּא דְכָל עַמָּךְ יִשְׂרָאֵל. לְטַב וּלְחַיִּין וְלִשְׁלָם.\n\nחזן - גַּדְּלוּ לַיהוה אִתִּי וּנְרוֹמְמָה שְׁמוֹ יַחְדָּו:\nקהל - לְךָ יהוה הַגְּדֻלָּה וְהַגְּבוּרָה וְהַתִּפְאֶרֶת וְהַנֵּצַח וְהַהוֹד כִּי כֹל בַּשָּׁמַיִם וּבָאָרֶץ: לְךָ יהוה הַמַּמְלָכָה וְהַמִּתְנַשֵּׂא לְכֹל לְרֹאשׁ: רוֹמְמוּ יהוה אֱלֹהֵינוּ וְהִשְׁתַּחֲווּ לַהֲדֹם רַגְלָיו קָדוֹשׁ הוּא: רוֹמְמוּ יהוה אֱלֹהֵינוּ וְהִשְׁתַּחֲווּ לְהַר קָדְשׁוֹ כִּי קָדוֹשׁ יהוה אֱלֹהֵינוּ:\n\nאַב הָרַחֲמִים, הוּא יְרַחֵם עַם עֲמוּסִים, וְיִזְכּוֹר בְּרִית אֵיתָנִים, וְיַצִּיל נַפְשׁוֹתֵינוּ מִן הַשָּׁעוֹת הָרָעוֹת, וְיִגְעַר בְּיֵצֶר הָרָע מִן הַנְּשוּאִים, וְיָחֹן אוֹתָנוּ לִפְלֵיטַת עוֹלָמִים, וִימַלֵּא מִשְׁאֲלוֹתֵינוּ בְּמִדָּה טוֹבָה, יְשׁוּעָה וְרַחֲמִים.","cond":["tora"]},{"kind":"header","text":"קריאת התורה","cond":["tora"]},{"kind":"instruction","text":"קריאת התורה","cond":["tora"]},{"kind":"instruction","text":"לפני הקריאה מברך העולה:","cond":["tora"]},{"kind":"instruction","text":"חזן:","cond":["tora"]},{"kind":"text","text":"בָּרְכוּ אֶת יהוה הַמְבֹרָךְ.","cond":["tora"]},{"kind":"instruction","text":"קהל וחזן:","cond":["tora"]},{"kind":"text","text":"בָּרוּךְ יהוה הַמְבֹרָךְ לְעוֹלָם וָעֶד.","cond":["tora"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר בָּחַר בָּנוּ מִכָּל הָעַמִּים וְנָתַן לָנוּ אֶת תּוֹרָתוֹ. בָּרוּךְ אַתָּה יהוה, נוֹתֵן הַתּוֹרָה.","cond":["tora"]},{"kind":"instruction","text":"לאחר הקריאה מברך העולה:","cond":["tora"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר נָתַן לָנוּ תּוֹרַת אֱמֶת וְחַיֵּי עוֹלָם נָטַע בְּתוֹכֵנוּ. בָּרוּךְ אַתָּה יהוה, נוֹתֵן הַתּוֹרָה.\n\n=====","cond":["tora"]},{"kind":"header","text":"ברכת הגומל","cond":["tora"]},{"kind":"instruction","text":"ברכת הגומל","cond":["tora"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַגּוֹמֵל לְחַיָּבִים טוֹבוֹת, שֶגְּמָלַנִי כָּל טוֹב.\n\nקהל - אָמֵן. מִי שֶגְּמָלְךָ טוֹב, הוּא יִגְמָלְךָ כָּל טוֹב, סֶלָה.","cond":["tora"]},{"kind":"instruction","text":"חצי קדיש","cond":["tora"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":["tora"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["tora","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["tora","ayt"]},{"kind":"instruction","text":"הגבהה וגלילה","cond":["tora"]},{"kind":"text","text":"וְזֹאת הַתּוֹרָה אֲשֶׁר שָׂם מֹשֶׁה לִפְנֵי בְּנֵי יִשְׂרָאֵל: עַל פִּי יהוה בְּיַד מֹשֶׁה:","cond":["tora"]},{"kind":"text","text":"יְהִי רָצוֹן מִלִּפְנֵי אָבִינוּ שֶׁבַּשָּׁמַיִם לְכוֹנֵן אֶת בֵּית חַיֵּינוּ, וּלְהָשִׁיב אֶת שְׁכִינָתוֹ בְּתוֹכֵנוּ בִּמְהֵרָה בְיָמֵינוּ, וְנֹאמַר אָמֵן.\n\nיְהִי רָצוֹן מִלִּפְנֵי אָבִינוּ שֶׁבַּשָּׁמַיִם לְרַחֵם עָלֵינוּ וְעַל פְּלֵיטָתֵינוּ, וְלִמְנוֹעַ מַשְׁחִית וּמַגֵּפָה מֵעָלֵינוּ וּמֵעַל כָּל עַמּוֹ בֵּית יִשְׂרָאֵל, וְנֹאמַר אָמֵן.\n\nיְהִי רָצוֹן מִלִּפְנֵי אָבִינוּ שֶׁבַּשָּׁמַיִם לְקַיֵּם בָּנוּ חַכְמֵי יִשְׂרָאֵל, הֵם וּנְשֵׁיהֶם וּבְנֵיהֶם וּבְנוֹתֵיהֶם, וְתַלְמִידֵיהֶם וְתַלְמִידֵי תַלְמִידֵיהֶם, בְּכָל מְקוֹמוֹת מוֹשְׁבוֹתֵיהֶם, וְנֹאמַר אָמֵן.\n\nיְהִי רָצוֹן מִלִּפְנֵי אָבִינוּ שֶׁבַּשָּׁמַיִם שֶׁנִּשְׁמַע וְנִתְבַּשֵׂר בְּשׂוֹרוֹת טוֹבוֹת, יְשׁוּעוֹת וְנֶחָמוֹת, וִיקַבֵּץ נִדָּחֵינוּ מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ. וְנֹאמַר אָמֵן.\n\nאַחֵינוּ כָּל בֵּית יִשְׂרָאֵל, הַנְּתוּנִים בְּצָרָה וּבְשִׁבְיָה, הָעוֹמְדִים בֵּין בַּיָּם וּבֵין בַּיַּבָּשָׁה, הַמָּקוֹם יְרַחֵם עֲלֵיהֶם וְיוֹצִיאֵם מִצָּרָה לִרְוָחָה, וּמֵאֲפֵלָה לְאוֹרָה, וּמִשִּׁעְבּוּד לִגְאֻלָּה, הַשְׁתָּא בַּעֲגָלָא וּבִזְמַן קָרִיב, וְנֹאמַר אָמֵן.","cond":["tora","monThuTachanun"]},{"kind":"header","text":"הפטרה","cond":["tishaaBeav"]},{"kind":"instruction","text":"הפטרה","cond":["tishaaBeav"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר בָּחַר בִּנְבִיאִים טוֹבִים וְרָצָה בְדִבְרֵיהֶם הַנֶּאֱמָרִים בֶּאֱמֶת. בָּרוּךְ אַתָּה יהוה, הַבּוֹחֵר בַּתּוֹרָה וּבְמֹשֶׁה עַבְדּוֹ וּבְיִשְׂרָאֵל עַמּוֹ וּבִנְבִיאֵי הָאֱמֶת וָצֶדֶק.\n\nאָסֹף אֲסִיפֵם נְאֻם יהוה אֵין עֲנָבִים בַּגֶּפֶן וְאֵין תְּאֵנִים בַּתְּאֵנָה וְהֶעָלֶה נָבֵל וָאֶתֵּן לָהֶם יַעַבְרוּם: עַל מָה אֲנַחְנוּ יֹשְׁבִים הֵאָסְפוּ וְנָבוֹא אֶל עָרֵי הַמִּבְצָר וְנִדְּמָה שָּׁם כִּי יהוה אֱלֹהֵינוּ הֲדִמָּנוּ וַיַּשְׁקֵנוּ מֵי רֹאשׁ כִּי חָטָאנוּ לַיהוה: קַוֵּה לְשָׁלוֹם וְאֵין טוֹב לְעֵת מַרְפֵּה וְהִנֵּה בְעָתָה: מִדָּן נִשְׁמַע נַחְרַת סוּסָיו מִקּוֹל מִצְהֲלוֹת אַבִּירָיו רָעֲשָׁה כָּל הָאָרֶץ וַיָּבוֹאוּ וַיֹּאכְלוּ אֶרֶץ וּמְלוֹאָהּ עִיר וְיֹשְׁבֵי בָהּ: כִּי הִנְנִי מְשַׁלֵּחַ בָּכֶם נְחָשִׁים צִפְעֹנִים אֲשֶׁר אֵין לָהֶם לָחַשׁ וְנִשְּׁכוּ אֶתְכֶם נְאֻם יהוה: מַבְלִיגִיתִי עֲלֵי יָגוֹן עָלַי לִבִּי דַוָּי: הִנֵּה קוֹל שַׁוְעַת בַּת עַמִּי מֵאֶרֶץ מַרְחַקִּים הַיהוה אֵין בְּצִיּוֹן אִם מַלְכָּהּ אֵין בָּהּ מַדּוּעַ הִכְעִסוּנִי בִּפְסִלֵיהֶם בְּהַבְלֵי נֵכָר: עָבַר קָצִיר כָּלָה קָיִץ וַאֲנַחְנוּ לוֹא נוֹשָׁעְנוּ: עַל שֶׁבֶר בַּת עַמִּי הָשְׁבָּרְתִּי קָדַרְתִּי שַׁמָּה הֶחֱזִקָתְנִי: הַצֳרִי אֵין בְּגִלְעָד אִם רֹפֵא אֵין שָׁם כִּי מַדּוּעַ לֹא עָלְתָה אֲרֻכַת בַּת עַמִּי: מִי יִתֵּן רֹאשִׁי מַיִם וְעֵינִי מְקוֹר דִּמְעָה וְאֶבְכֶּה יוֹמָם וָלַיְלָה אֵת חַלְלֵי בַת עַמִּי: מִי יִתְּנֵנִי בַמִּדְבָּר מְלוֹן אֹרְחִים וְאֶעֶזְבָה אֶת עַמִּי וְאֵלְכָה מֵאִתָּם כִּי כֻלָּם מְנָאֲפִים עֲצֶרֶת בֹּגְדִים: וַיַּדְרְכוּ אֶת לְשׁוֹנָם קַשְׁתָּם שֶׁקֶר וְלֹא לֶאֱמוּנָה גָּבְרוּ בָאָרֶץ כִּי מֵרָעָה אֶל רָעָה יָצָאוּ וְאֹתִי לֹא יָדָעוּ נְאֻם יהוה: אִישׁ מֵרֵעֵהוּ הִשָּׁמֵרוּ וְעַל כָּל אָח אַל תִּבְטָחוּ כִּי כָל אָח עָקוֹב יַעְקֹב וְכָל רֵעַ רָכִיל יַהֲלֹךְ: וְאִישׁ בְּרֵעֵהוּ יְהָתֵלּוּ וֶאֱמֶת לֹא יְדַבֵּרוּ לִמְּדוּ לְשׁוֹנָם דַּבֶּר שֶׁקֶר הַעֲוֵה נִלְאוּ: שִׁבְתְּךָ בְּתוֹךְ מִרְמָה בְּמִרְמָה מֵאֲנוּ דַעַת אוֹתִי נְאֻם יהוה: לָכֵן כֹּה אָמַר יהוה צְבָאוֹת הִנְנִי צוֹרְפָם וּבְחַנְתִּים כִּי אֵיךְ אֶעֱשֶׂה מִפְּנֵי בַּת עַמִּי: חֵץ שָׁחוּט לְשׁוֹנָם מִרְמָה דִבֵּר בְּפִיו שָׁלוֹם אֶת רֵעֵהוּ יְדַבֵּר וּבְקִרְבּוֹ יָשִׂים אָרְבּוֹ: הַעַל אֵלֶּה לֹא אֶפְקָד בָּם נְאֻם יהוה אִם בְּגוֹי אֲשֶׁר כָּזֶה לֹא תִתְנַקֵּם נַפְשִׁי: עַל הֶהָרִים אֶשָּׂא בְכִי וָנֶהִי וְעַל נְאוֹת מִדְבָּר קִינָה כִּי נִצְּתוּ מִבְּלִי אִישׁ עֹבֵר וְלֹא שָׁמְעוּ קוֹל מִקְנֶה מֵעוֹף הַשָּׁמַיִם וְעַד בְּהֵמָה נָדְדוּ הָלָכוּ: וְנָתַתִּי אֶת יְרוּשָׁלַיִם לְגַלִּים מְעוֹן תַּנִּים וְאֶת עָרֵי יְהוּדָה אֶתֵּן שְׁמָמָה מִבְּלִי יוֹשֵׁב: מִי הָאִישׁ הֶחָכָם וְיָבֵן אֶת זֹאת וַאֲשֶׁר דִּבֶּר פִּי יהוה אֵלָיו וְיַגִּדָהּ עַל מָה אָבְדָה הָאָרֶץ נִצְּתָה כַמִּדְבָּר מִבְּלִי עֹבֵר: וַיֹּאמֶר יהוה עַל עָזְבָם אֶת תּוֹרָתִי אֲשֶׁר נָתַתִּי לִפְנֵיהֶם וְלֹא שָׁמְעוּ בְקוֹלִי וְלֹא הָלְכוּ בָהּ: וַיֵּלְכוּ אַחֲרֵי שְׁרִרוּת לִבָּם וְאַחֲרֵי הַבְּעָלִים אֲשֶׁר לִמְּדוּם אֲבוֹתָם: לָכֵן כֹּה אָמַר יהוה צְבָאוֹת אֱלֹהֵי יִשְׂרָאֵל הִנְנִי מַאֲכִילָם אֶת הָעָם הַזֶּה לַעֲנָה וְהִשְׁקִיתִים מֵי רֹאשׁ: וַהֲפִצוֹתִים בַּגּוֹיִם אֲשֶׁר לֹא יָדְעוּ הֵמָּה וַאֲבוֹתָם וְשִׁלַּחְתִּי אַחֲרֵיהֶם אֶת הַחֶרֶב עַד כַּלּוֹתִי אוֹתָם: כֹּה אָמַר יהוה צְבָאוֹת הִתְבּוֹנְנוּ וְקִרְאוּ לַמְקוֹנְנוֹת וּתְבוֹאֶינָה וְאֶל הַחֲכָמוֹת שִׁלְחוּ וְתָבוֹאנָה: וּתְמַהֵרְנָה וְתִשֶּׂנָה עָלֵינוּ נֶהִי וְתֵרַדְנָה עֵינֵינוּ דִּמְעָה וְעַפְעַפֵּינוּ יִזְּלוּ מָיִם: כִּי קוֹל נְהִי נִשְׁמַע מִצִּיּוֹן אֵיךְ שֻׁדָּדְנוּ בֹּשְׁנוּ מְאֹד כִּי עָזַבְנוּ אָרֶץ כִּי הִשְׁלִיכוּ מִשְׁכְּנוֹתֵינוּ: כִּי שְׁמַעְנָה נָשִׁים דְּבַר יהוה וְתִקַּח אָזְנְכֶם דְּבַר פִּיו וְלַמֵּדְנָה בְנוֹתֵיכֶם נֶהִי וְאִשָּׁה רְעוּתָהּ קִינָה: כִּי עָלָה מָוֶת בְּחַלּוֹנֵינוּ בָּא בְּאַרְמְנוֹתֵינוּ לְהַכְרִית עוֹלָל מִחוּץ בַּחוּרִים מֵרְחֹבוֹת: דַּבֵּר כֹּה נְאֻם יהוה וְנָפְלָה נִבְלַת הָאָדָם כְּדֹמֶן עַל פְּנֵי הַשָּׂדֶה וּכְעָמִיר מֵאַחֲרֵי הַקֹּצֵר וְאֵין מְאַסֵּף: כֹּה אָמַר יהוה אַל יִתְהַלֵּל חָכָם בְּחָכְמָתוֹ וְאַל יִתְהַלֵּל הַגִּבּוֹר בִּגְבוּרָתוֹ אַל יִתְהַלֵּל עָשִׁיר בְּעָשְׁרוֹ: כִּי אִם בְּזֹאת יִתְהַלֵּל הַמִּתְהַלֵּל הַשְׂכֵּל וְיָדֹעַ אוֹתִי כִּי אֲנִי יהוה עֹשֶׂה חֶסֶד מִשְׁפָּט וּצְדָקָה בָּאָרֶץ כִּי בְאֵלֶּה חָפַצְתִּי נְאֻם יהוה:\n\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעולָם, צוּר כָּל הָעוֹלָמִים, צַדִּיק בְּכָל הַדּוֹרוֹת, הָאֵל הַנֶּאֱמָן הָאוֹמֵר וְעוֹשֶׂה, הַמְדַבֵּר וּמְקַיֵּם שֶׁכָּל דְּבָרָיו אֱמֶת וָצֶדֶק. נֶאֱמָן אַתָּה הוּא יהוה אֱלֹהֵינוּ וְנֶאֱמָנִים דְּבָרֶיךָ, וְדָבָר אֶחָד מִדְּבָרֶיךָ אָחוֹר לֹא יָשׁוּב רֵיקָם, כִּי אֵל מֶלֶךְ נֶאֱמָן וְרַחֲמָן אָתָּה. בָּרוּךְ אַתָּה יהוה, הָאֵל הַנֶּאֱמָן בְּכָל דְּבָרָיו.\n\nרַחֵם עַל צִיּוֹן כִּי הִיא בֵּית חַיֵּינוּ, וְלַעֲלוּבַת נֶפֶשׁ תּוֹשִׁיעַ בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יהוה, מְשַׂמֵּחַ צִיּוֹן בְּבָנֶיהָ.\n\nשַׂמְּחֵנוּ יהוה אֱלֹהֵינוּ בְּאֵלִיָּהוּ הַנָּבִיא עַבְדֶּךָ וּבְמַלְכוּת בֵּית דָּוִד מְשִׁיחֶךָ, בִּמְהֵרָה יָבוֹא וְיָגֵל לִבֵּנוּ, עַל כִּסְאוֹ לֹא יֵשֵׁב זָר וְלֹא יִנְחֲלוּ עוֹד אֲחֵרִים אֶת כְּבוֹדוֹ, כִּי בְשֵׁם קָדְשְׁךָ נִשְׁבַּעְתָּ לוֹ שֶׁלֹּא יִכְבֶּה נֵרוֹ לְעוֹלָם וָעֶד. בָּרוּךְ אַתָּה יהוה, מָגֵן דָּוִד.","cond":["tishaaBeav"]},{"kind":"header","text":"מגילת אסתר","cond":["megilatEster"]},{"kind":"instruction","text":"הקורא את המגילה מברך לפניה שלוש ברכות גם בלילה וגם ביום. לדעת השו\"ע מברכים שהחיינו רק בלילה (ואם לא קרא בלילה יברך ביום). בברכת שהחיינו ביום יכוון גם על שאר מצוות היום: מתנות לאביונים, משלוח מנות ומשתה ושמחה. הנוהגים כדעת השו\"ע יכוונו על זה בלילה.","cond":["megilatEster"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ עַל מִקְרָא מְגִלָּה.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁעָשָׂה נִסִּים לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁהֶחֱיָנוּ וְקִיְּמָנוּ וְהִגִּיעָנוּ לַזְּמַן הַזֶּה.","cond":["megilatEster"]},{"kind":"header","text":"פרק א'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק א'","cond":["megilatEster"]},{"kind":"text","text":"וַיְהִי בִּימֵי אֲחַשְׁוֵרוֹשׁ, הוּא אֲחַשְׁוֵרוֹשׁ הַמֹּלֵךְ מֵהֹדּוּ וְעַד כּוּשׁ, שֶׁבַע וְעֶשְׂרִים וּמֵאָה מְדִינָה: בַּיָּמִים הָהֵם, כְּשֶׁבֶת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ עַל כִּסֵּא מַלְכוּתוֹ אֲשֶׁר בְּשׁוּשַׁן הַבִּירָה: בִּשְׁנַת שָׁלוֹשׁ לְמָלְכוֹ עָשָׂה מִשְׁתֶּה לְכָל שָׂרָיו וַעֲבָדָיו, חֵיל פָּרַס וּמָדַי הַפַּרְתְּמִים וְשָׂרֵי הַמְּדִינוֹת לְפָנָיו: בְּהַרְאֹתוֹ אֶת עֹשֶׁר כְּבוֹד מַלְכוּתוֹ וְאֶת יְקָר תִּפְאֶרֶת גְּדוּלָּתוֹ, יָמִים רַבִּים שְׁמוֹנִים וּמְאַת יוֹם: וּבִמְלוֹאת הַיָּמִים הָאֵלֶּה עָשָׂה הַמֶּלֶךְ לְכָל הָעָם הַנִּמְצְאִים בְּשׁוּשַׁן הַבִּירָה לְמִגָּדוֹל וְעַד קָטָן מִשְׁתֶּה שִׁבְעַת יָמִים, בַּחֲצַר גִּנַּת בִּיתַן הַמֶּלֶךְ: חוּר כַּרְפַּס וּתְכֵלֶת אָחוּז בְּחַבְלֵי בוּץ וְאַרְגָּמָן עַל גְּלִילֵי כֶסֶף וְעַמּוּדֵי שֵׁשׁ, מִטּוֹת זָהָב וָכֶסֶף עַל רִצְפַת בַּהַט וָשֵׁשׁ וְדַר וְסֹחָרֶת: וְהַשְׁקוֹת בִּכְלֵי זָהָב וְכֵלִים מִכֵּלִים שׁוֹנִים, וְיֵין מַלְכוּת רָב כְּיַד הַמֶּלֶךְ: וְהַשְּׁתִיָּה כַדָּת אֵין אֹנֵס, כִּי כֵן יִסַּד הַמֶּלֶךְ עַל כָּל רַב בֵּיתוֹ לַעֲשׂוֹת כִּרְצוֹן אִישׁ וָאִישׁ: גַּם וַשְׁתִּי הַמַּלְכָּה עָשְׂתָה מִשְׁתֵּה נָשִׁים, בֵּית הַמַּלְכוּת אֲשֶׁר לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: בַּיּוֹם הַשְּׁבִיעִי כְּטוֹב לֵב הַמֶּלֶךְ בַּיָּיִן, אָמַר לִמְהוּמָן בִּזְּתָא חַרְבוֹנָא בִּגְתָא וַאֲבַגְתָא זֵתַר וְכַרְכַּס שִׁבְעַת הַסָּרִיסִים הַמְשָׁרְתִים אֶת פְּנֵי הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: לְהָבִיא אֶת וַשְׁתִּי הַמַּלְכָּה לִפְנֵי הַמֶּלֶךְ בְּכֶתֶר מַלְכוּת, לְהַרְאוֹת הָעַמִּים וְהַשָּׂרִים אֶת יָפְיָהּ, כִּי טוֹבַת מַרְאֶה הִיא: וַתְּמָאֵן הַמַּלְכָּה וַשְׁתִּי לָבוֹא בִּדְבַר הַמֶּלֶךְ אֲשֶׁר בְּיַד הַסָּרִיסִים, וַיִּקְצֹף הַמֶּלֶךְ מְאֹד וַחֲמָתוֹ בָּעֲרָה בוֹ: וַיֹּאמֶר הַמֶּלֶךְ לַחֲכָמִים יֹדְעֵי הָעִתִּים, כִּי כֵן דְּבַר הַמֶּלֶךְ לִפְנֵי כָּל יֹדְעֵי דָּת וָדִין: וְהַקָּרֹב אֵלָיו כַּרְשְׁנָא שֵׁתָר אַדְמָתָא תַרְשִׁישׁ מֶרֶס מַרְסְנָא מְמוּכָן, שִׁבְעַת שָׂרֵי פָּרַס וּמָדַי רֹאֵי פְּנֵי הַמֶּלֶךְ הַיֹּשְׁבִים רִאשֹׁנָה בַּמַּלְכוּת: כְּדָת מַה לַּעֲשׂוֹת בַּמַּלְכָּה וַשְׁתִּי, עַל אֲשֶׁר לֹא עָשְׂתָה אֶת מַאֲמַר הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ בְּיַד הַסָּרִיסִים: וַיֹּאמֶר מְמוּכָן לִפְנֵי הַמֶּלֶךְ וְהַשָּׂרִים, לֹא עַל הַמֶּלֶךְ לְבַדּוֹ עָוְתָה וַשְׁתִּי הַמַּלְכָּה, כִּי עַל כָּל הַשָּׂרִים וְעַל כָּל הָעַמִּים אֲשֶׁר בְּכָל מְדִינוֹת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: כִּי יֵצֵא דְבַר הַמַּלְכָּה עַל כָּל הַנָּשִׁים לְהַבְזוֹת בַּעְלֵיהֶן בְּעֵינֵיהֶן, בְּאָמְרָם הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ אָמַר לְהָבִיא אֶת וַשְׁתִּי הַמַּלְכָּה לְפָנָיו וְלֹא בָאָה: וְהַיּוֹם הַזֶּה תֹּאמַרְנָה שָׂרוֹת פָּרַס וּמָדַי אֲשֶׁר שָׁמְעוּ אֶת דְּבַר הַמַּלְכָּה לְכֹל שָׂרֵי הַמֶּלֶךְ, וּכְדַי בִּזָּיוֹן וָקָצֶף: אִם עַל הַמֶּלֶךְ טוֹב יֵצֵא דְבַר מַלְכוּת מִלְּפָנָיו וְיִכָּתֵב בְּדָתֵי פָרַס וּמָדַי וְלֹא יַעֲבוֹר, אֲשֶׁר לֹא תָבוֹא וַשְׁתִּי לִפְנֵי הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ וּמַלְכוּתָהּ יִתֵּן הַמֶּלֶךְ לִרְעוּתָהּ הַטּוֹבָה מִמֶּנָּה: וְנִשְׁמַע פִּתְגָם הַמֶּלֶךְ אֲשֶׁר יַעֲשֶׂה בְּכָל מַלְכוּתוֹ כִּי רַבָּה הִיא, וְכָל הַנָּשִׁים יִתְּנוּ יְקָר לְבַעְלֵיהֶן לְמִגָּדוֹל וְעַד קָטָן: וַיִּיטַב הַדָּבָר בְּעֵינֵי הַמֶּלֶךְ וְהַשָּׂרִים, וַיַּעַשׂ הַמֶּלֶךְ כִּדְבַר מְמוּכָן: וַיִּשְׁלַח סְפָרִים אֶל כָּל מְדִינוֹת הַמֶּלֶךְ, אֶל מְדִינָה וּמְדִינָה כִּכְתָבָהּ וְאֶל עַם וָעָם כִּלְשׁוֹנוֹ, לִהְיוֹת כָּל אִישׁ שֹׂרֵר בְּבֵיתוֹ וּמְדַבֵּר כִּלְשׁוֹן עַמּוֹ:","cond":["megilatEster"]},{"kind":"header","text":"פרק ב'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ב'","cond":["megilatEster"]},{"kind":"text","text":"אַחַר הַדְּבָרִים הָאֵלֶּה כְּשֹׁךְ חֲמַת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, זָכַר אֶת וַשְׁתִּי וְאֵת אֲשֶׁר עָשָׂתָה וְאֵת אֲשֶׁר נִגְזַר עָלֶיהָ: וַיֹּאמְרוּ נַעֲרֵי הַמֶּלֶךְ מְשָׁרְתָיו, יְבַקְשׁוּ לַמֶּלֶךְ נְעָרוֹת בְּתוּלוֹת טוֹבוֹת מַרְאֶה: וְיַפְקֵד הַמֶּלֶךְ פְּקִידִים בְּכָל מְדִינוֹת מַלְכוּתוֹ, וְיִקְבְּצוּ אֶת כָּל נַעֲרָה בְתוּלָה טוֹבַת מַרְאֶה אֶל שׁוּשַׁן הַבִּירָה אֶל בֵּית הַנָּשִׁים אֶל יַד הֵגֶא סְרִיס הַמֶּלֶךְ שֹׁמֵר הַנָּשִׁים, וְנָתוֹן תַּמְרוּקֵיהֶן: וְהַנַּעֲרָה אֲשֶׁר תִּיטַב בְּעֵינֵי הַמֶּלֶךְ תִּמְלֹךְ תַּחַת וַשְׁתִּי, וַיִּיטַב הַדָּבָר בְּעֵינֵי הַמֶּלֶךְ וַיַּעַשׂ כֵּן:","cond":["megilatEster"]},{"kind":"special","text":"אִישׁ יְהוּדִי הָיָה בְּשׁוּשַׁן הַבִּירָה, וּשְׁמוֹ מָרְדֳּכַי בֶּן יָאִיר בֶּן שִׁמְעִי בֶּן קִישׁ אִישׁ יְמִינִי:","cond":["megilatEster"]},{"kind":"text","text":"אֲשֶׁר הָגְלָה מִירוּשָׁלַיִם עִם הַגֹּלָה אֲשֶׁר הָגְלְתָה עִם יְכָנְיָה מֶלֶךְ יְהוּדָה, אֲשֶׁר הֶגְלָה נְבוּכַדְנֶאצַּר מֶלֶךְ בָּבֶל: וַיְהִי אֹמֵן אֶת הֲדַסָּה הִיא אֶסְתֵּר בַּת דֹּדוֹ כִּי אֵין לָהּ אָב וָאֵם, וְהַנַּעֲרָה יְפַת תֹּאַר וְטוֹבַת מַרְאֶה וּבְמוֹת אָבִיהָ וְאִמָּהּ לְקָחָהּ מָרְדֳּכַי לוֹ לְבַת: וַיְהִי בְּהִשָּׁמַע דְּבַר הַמֶּלֶךְ וְדָתוֹ, וּבְהִקָּבֵץ נְעָרוֹת רַבּוֹת אֶל שׁוּשַׁן הַבִּירָה אֶל יַד הֵגָי, וַתִּלָּקַח אֶסְתֵּר אֶל בֵּית הַמֶּלֶךְ אֶל יַד הֵגַי שֹׁמֵר הַנָּשִׁים: וַתִּיטַב הַנַּעֲרָה בְעֵינָיו וַתִּשָּׂא חֶסֶד לְפָנָיו, וַיְבַהֵל אֶת תַּמְרוּקֶיהָ וְאֶת מָנוֹתֶהָ לָתֵת לָהּ, וְאֵת שֶׁבַע הַנְּעָרוֹת הָרְאֻיוֹת לָתֶת לָהּ מִבֵּית הַמֶּלֶךְ, וַיְשַׁנֶּהָ וְאֶת נַעֲרוֹתֶיהָ לְטוֹב בֵּית הַנָּשִׁים: לֹא הִגִּידָה אֶסְתֵּר אֶת עַמָּהּ וְאֶת מוֹלַדְתָּהּ, כִּי מָרְדֳּכַי צִוָּה עָלֶיהָ אֲשֶׁר לֹא תַגִּיד: וּבְכָל יוֹם וָיוֹם מָרְדֳּכַי מִתְהַלֵּךְ לִפְנֵי חֲצַר בֵּית הַנָּשִׁים, לָדַעַת אֶת שְׁלוֹם אֶסְתֵּר וּמַה יֵּעָשֶׂה בָּהּ: וּבְהַגִּיעַ תֹּר נַעֲרָה וְנַעֲרָה לָבוֹא אֶל הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, מִקֵּץ הֱיוֹת לָהּ כְּדָת הַנָּשִׁים שְׁנֵים עָשָׂר חֹדֶשׁ כִּי כֵּן יִמְלְאוּ יְמֵי מְרוּקֵיהֶן, שִׁשָּׁה חֳדָשִׁים בְּשֶׁמֶן הַמֹּר וְשִׁשָּׁה חֳדָשִׁים בַּבְּשָׂמִים וּבְתַמְרוּקֵי הַנָּשִׁים: וּבָזֶה הַנַּעֲרָה בָּאָה אֶל הַמֶּלֶךְ, אֵת כָּל אֲשֶׁר תֹּאמַר יִנָּתֵן לָהּ לָבוֹא עִמָּהּ מִבֵּית הַנָּשִׁים עַד בֵּית הַמֶּלֶךְ: בָּעֶרֶב הִיא בָאָה וּבַבֹּקֶר הִיא שָׁבָה אֶל בֵּית הַנָּשִׁים שֵׁנִי, אֶל יַד שַׁעֲשְׁגַז סְרִיס הַמֶּלֶךְ שֹׁמֵר הַפִּילַגְשִׁים, לֹא תָבוֹא עוֹד אֶל הַמֶּלֶךְ כִּי אִם חָפֵץ בָּהּ הַמֶּלֶךְ וְנִקְרְאָה בְשֵׁם: וּבְהַגִּיעַ תֹּר אֶסְתֵּר בַּת אֲבִיחַיִל דֹּד מָרְדֳּכַי אֲשֶׁר לָקַח לוֹ לְבַת לָבוֹא אֶל הַמֶּלֶךְ, לֹא בִקְשָׁה דָּבָר כִּי אִם אֶת אֲשֶׁר יֹאמַר הֵגַי סְרִיס הַמֶּלֶךְ שֹׁמֵר הַנָּשִׁים, וַתְּהִי אֶסְתֵּר נֹשֵׂאת חֵן בְּעֵינֵי כָּל רֹאֶיהָ: וַתִּלָּקַח אֶסְתֵּר אֶל הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ אֶל בֵּית מַלְכוּתוֹ בַּחֹדֶשׁ הָעֲשִׂירִי הוּא חֹדֶשׁ טֵבֵת, בִּשְׁנַת שֶׁבַע לְמַלְכוּתוֹ: וַיֶּאֱהַב הַמֶּלֶךְ אֶת אֶסְתֵּר מִכָּל הַנָּשִׁים וַתִּשָּׂא חֵן וָחֶסֶד לְפָנָיו מִכָּל הַבְּתוּלֹת, וַיָּשֶׂם כֶּתֶר מַלְכוּת בְּרֹאשָׁהּ וַיַּמְלִיכֶהָ תַּחַת וַשְׁתִּי: וַיַּעַשׂ הַמֶּלֶךְ מִשְׁתֶּה גָדוֹל לְכָל שָׂרָיו וַעֲבָדָיו, אֵת מִשְׁתֵּה אֶסְתֵּר, וַהֲנָחָה לַמְּדִינוֹת עָשָׂה וַיִּתֵּן מַשְׂאֵת כְּיַד הַמֶּלֶךְ: וּבְהִקָּבֵץ בְּתוּלוֹת שֵׁנִית, וּמָרְדֳּכַי יֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ: אֵין אֶסְתֵּר מַגֶּדֶת מוֹלַדְתָּהּ וְאֶת עַמָּהּ כַּאֲשֶׁר צִוָּה עָלֶיהָ מָרְדֳּכַי, וְאֶת מַאֲמַר מָרְדֳּכַי אֶסְתֵּר עֹשָׂה כַּאֲשֶׁר הָיְתָה בְאָמְנָה אִתּוֹ: בַּיָּמִים הָהֵם, וּמָרְדֳּכַי יֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ, קָצַף בִּגְתָן וָתֶרֶשׁ שְׁנֵי סָרִיסֵי הַמֶּלֶךְ מִשֹּׁמְרֵי הַסַּף וַיְבַקְשׁוּ לִשְׁלֹחַ יָד בַּמֶּלֶךְ אֲחַשְׁוֵרֹשׁ: וַיִּוָּדַע הַדָּבָר לְמָרְדֳּכַי וַיַּגֵּד לְאֶסְתֵּר הַמַּלְכָּה, וַתֹּאמֶר אֶסְתֵּר לַמֶּלֶךְ בְּשֵׁם מָרְדֳּכַי: וַיְבֻקַּשׁ הַדָּבָר וַיִּמָּצֵא וַיִּתָּלוּ שְׁנֵיהֶם עַל עֵץ, וַיִּכָּתֵב בְּסֵפֶר דִּבְרֵי הַיָּמִים לִפְנֵי הַמֶּלֶךְ:","cond":["megilatEster"]},{"kind":"header","text":"פרק ג'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ג'","cond":["megilatEster"]},{"kind":"text","text":"אַחַר הַדְּבָרִים הָאֵלֶּה גִּדַּל הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ אֶת הָמָן בֶּן הַמְּדָתָא הָאֲגָגִי וַיְנַשְּׂאֵהוּ, וַיָּשֶׂם אֶת כִּסְאוֹ מֵעַל כָּל הַשָּׂרִים אֲשֶׁר אִתּוֹ: וְכָל עַבְדֵי הַמֶּלֶךְ אֲשֶׁר בְּשַׁעַר הַמֶּלֶךְ כֹּרְעִים וּמִשְׁתַּחֲוִים לְהָמָן, כִּי כֵן צִוָּה לוֹ הַמֶּלֶךְ, וּמָרְדֳּכַי לֹא יִכְרַע וְלֹא יִשְׁתַּחֲוֶה: וַיֹּאמְרוּ עַבְדֵי הַמֶּלֶךְ אֲשֶׁר בְּשַׁעַר הַמֶּלֶךְ לְמָרְדֳּכַי, מַדּוּעַ אַתָּה עוֹבֵר אֵת מִצְוַת הַמֶּלֶךְ: וַיְהִי כְּאָמְרָם אֵלָיו יוֹם וָיוֹם וְלֹא שָׁמַע אֲלֵיהֶם, וַיַּגִּידוּ לְהָמָן לִרְאוֹת הֲיַעַמְדוּ דִּבְרֵי מָרְדֳּכַי כִּי הִגִּיד לָהֶם אֲשֶׁר הוּא יְהוּדִי: וַיַּרְא הָמָן כִּי אֵין מָרְדֳּכַי כֹּרֵעַ וּמִשְׁתַּחֲוֶה לוֹ, וַיִּמָּלֵא הָמָן חֵמָה: וַיִּבֶז בְּעֵינָיו לִשְׁלֹח יָד בְּמָרְדֳּכַי לְבַדּוֹ כִּי הִגִּידוּ לוֹ אֶת עַם מָרְדֳּכַי, וַיְבַקֵּשׁ הָמָן לְהַשְׁמִיד אֶת כָּל הַיְּהוּדִים אֲשֶׁר בְּכָל מַלְכוּת אֲחַשְׁוֵרוֹשׁ עַם מָרְדֳּכַי: בַּחֹדֶשׁ הָרִאשׁוֹן הוּא חֹדֶשׁ נִיסָן בִּשְׁנַת שְׁתֵּים עֶשְׂרֵה לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, הִפִּיל פּוּר הוּא הַגּוֹרָל לִפְנֵי הָמָן מִיּוֹם לְיוֹם וּמֵחֹדֶשׁ לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר: וַיֹּאמֶר הָמָן לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ יֶשְׁנוֹ עַם אֶחָד מְפֻזָּר וּמְפֹרָד בֵּין הָעַמִּים בְּכֹל מְדִינוֹת מַלְכוּתֶךָ, וְדָתֵיהֶם שֹׁנוֹת מִכָּל עָם וְאֶת דָּתֵי הַמֶּלֶךְ אֵינָם עֹשִׂים וְלַמֶּלֶךְ אֵין שֹׁוֶה לְהַנִּיחָם: אִם עַל הַמֶּלֶךְ טוֹב יִכָּתֵב לְאַבְּדָם, וַעֲשֶׂרֶת אֲלָפִים כִּכַּר כֶּסֶף אֶשְׁקוֹל עַל יְדֵי עֹשֵׂי הַמְּלָאכָה לְהָבִיא אֶל גִּנְזֵי הַמֶּלֶךְ: וַיָּסַר הַמֶּלֶךְ אֶת טַבַּעְתּוֹ מֵעַל יָדוֹ, וַיִּתְּנָהּ לְהָמָן בֶּן הַמְּדָתָא הָאֲגָגִי צֹרֵר הַיְּהוּדִים: וַיֹּאמֶר הַמֶּלֶךְ לְהָמָן הַכֶּסֶף נָתוּן לָךְ, וְהָעָם לַעֲשׂוֹת בּוֹ כַּטּוֹב בְּעֵינֶיךָ: וַיִּקָּרְאוּ סֹפְרֵי הַמֶּלֶךְ בַּחֹדֶשׁ הָרִאשׁוֹן בִּשְׁלוֹשָׁה עָשָׂר יוֹם בּוֹ, וַיִּכָּתֵב כְּכָל אֲשֶׁר צִוָּה הָמָן אֶל אֲחַשְׁדַּרְפְּנֵי הַמֶּלֶךְ וְאֶל הַפַּחוֹת אֲשֶׁר עַל מְדִינָה וּמְדִינָה וְאֶל שָׂרֵי עַם וָעָם, מְדִינָה וּמְדִינָה כִּכְתָבָהּ וְעַם וָעָם כִּלְשׁוֹנוֹ, בְּשֵׁם הַמֶּלֶךְ אֲחַשְׁוֵרֹשׁ נִכְתָּב וְנֶחְתָּם בְּטַבַּעַת הַמֶּלֶךְ: וְנִשְׁלוֹחַ סְפָרִים בְּיַד הָרָצִים אֶל כָּל מְדִינוֹת הַמֶּלֶךְ, לְהַשְׁמִיד לַהֲרֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלוֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: פַּתְשֶׁגֶן הַכְּתָב לְהִנָּתֵן דָּת בְּכָל מְדִינָה וּמְדִינָה גָּלוּי לְכָל הָעַמִּים, לִהְיוֹת עֲתִדִים לַיּוֹם הַזֶּה: הָרָצִים יָצְאוּ דְחוּפִים בִּדְבַר הַמֶּלֶךְ וְהַדָּת נִתְּנָה בְּשׁוּשַׁן הַבִּירָה, וְהַמֶּלֶךְ וְהָמָן יָשְׁבוּ לִשְׁתּוֹת וְהָעִיר שׁוּשָׁן נָבוֹכָה:","cond":["megilatEster"]},{"kind":"header","text":"פרק ד'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ד'","cond":["megilatEster"]},{"kind":"text","text":"וּמָרְדֳּכַי יָדַע אֶת כָּל אֲשֶׁר נַעֲשָׂה וַיִּקְרַע מָרְדֳּכַי אֶת בְּגָדָיו וַיִּלְבַּשׁ שַׂק וָאֵפֶר, וַיֵּצֵא בְּתוֹךְ הָעִיר וַיִּזְעַק זְעָקָה גְדֹלָה וּמָרָה: וַיָּבוֹא עַד לִפְנֵי שַׁעַר הַמֶּלֶךְ, כִּי אֵין לָבוֹא אֶל שַׁעַר הַמֶּלֶךְ בִּלְבוּשׁ שָׂק: וּבְכָל מְדִינָה וּמְדִינָה מְקוֹם אֲשֶׁר דְּבַר הַמֶּלֶךְ וְדָתוֹ מַגִּיעַ, אֵבֶל גָּדוֹל לַיְּהוּדִים וְצוֹם וּבְכִי וּמִסְפֵּד, שַׂק וָאֵפֶר יֻצַּע לָרַבִּים: וַתָּבוֹאנָה נַעֲרוֹת אֶסְתֵּר וְסָרִיסֶיהָ וַיַּגִּידוּ לָהּ וַתִּתְחַלְחַל הַמַּלְכָּה מְאֹד, וַתִּשְׁלַח בְּגָדִים לְהַלְבִּישׁ אֶת מָרְדֳּכַי וּלְהָסִיר שַׂקּוֹ מֵעָלָיו וְלֹא קִבֵּל: וַתִּקְרָא אֶסְתֵּר לַהֲתָךְ מִסָּרִיסֵי הַמֶּלֶךְ אֲשֶׁר הֶעֱמִיד לְפָנֶיהָ וַתְּצַוֵּהוּ עַל מָרְדֳּכַי, לָדַעַת מַה זֶּה וְעַל מַה זֶּה: וַיֵּצֵא הֲתָךְ אֶל מָרְדֳּכַי, אֶל רְחוֹב הָעִיר אֲשֶׁר לִפְנֵי שַׁעַר הַמֶּלֶךְ: וַיַּגֶּד לוֹ מָרְדֳּכַי אֵת כָּל אֲשֶׁר קָרָהוּ, וְאֵת פָּרָשַׁת הַכֶּסֶף אֲשֶׁר אָמַר הָמָן לִשְׁקוֹל עַל גִּנְזֵי הַמֶּלֶךְ בַּיְּהוּדִים לְאַבְּדָם: וְאֶת פַּתְשֶׁגֶן כְּתָב הַדָּת אֲשֶׁר נִתַּן בְּשׁוּשָׁן לְהַשְׁמִידָם נָתַן לוֹ לְהַרְאוֹת אֶת אֶסְתֵּר וּלְהַגִּיד לָהּ, וּלְצַוּוֹת עָלֶיהָ לָבוֹא אֶל הַמֶּלֶךְ לְהִתְחַנֶּן לוֹ וּלְבַקֵּשׁ מִלְּפָנָיו עַל עַמָּהּ: וַיָּבוֹא הֲתָךְ, וַיַּגֵּד לְאֶסְתֵּר אֵת דִּבְרֵי מָרְדֳּכַי: וַתֹּאמֶר אֶסְתֵּר לַהֲתָךְ, וַתְּצַוֵּהוּ אֶל מָרְדֳּכַי: כָּל עַבְדֵי הַמֶּלֶךְ וְעַם מְדִינוֹת הַמֶּלֶךְ יוֹדְעִים אֲשֶׁר כָּל אִישׁ וְאִשָּׁה אֲשֶׁר יָבוֹא אֶל הַמֶּלֶךְ אֶל הֶחָצֵר הַפְּנִימִית אֲשֶׁר לֹא יִקָּרֵא אַחַת דָּתוֹ לְהָמִית, לְבַד מֵאֲשֶׁר יוֹשִׁיט לוֹ הַמֶּלֶךְ אֶת שַׁרְבִיט הַזָּהָב וְחָיָה, וַאֲנִי לֹא נִקְרֵאתִי לָבוֹא אֶל הַמֶּלֶךְ זֶה שְׁלוֹשִׁים יוֹם: וַיַּגִּידוּ לְמָרְדֳּכַי אֵת דִּבְרֵי אֶסְתֵּר: וַיֹּאמֶר מָרְדֳּכַי לְהָשִׁיב אֶל אֶסְתֵּר, אַל תְּדַמִּי בְנַפְשֵׁךְ לְהִמָּלֵט בֵּית הַמֶּלֶךְ מִכָּל הַיְּהוּדִים: כִּי אִם הַחֲרֵשׁ תַּחֲרִישִׁי בָּעֵת הַזֹּאת, רֶוַח וְהַצָּלָה יַעֲמוֹד לַיְּהוּדִים מִמָּקוֹם אַחֵר וְאַתְּ וּבֵית אָבִיךְ תֹּאבֵדוּ, וּמִי יוֹדֵעַ אִם לְעֵת כָּזֹאת הִגַּעַתְּ לַמַּלְכוּת: וַתֹּאמֶר אֶסְתֵּר לְהָשִׁיב אֶל מָרְדֳּכַי: לֵךְ כְּנוֹס אֶת כָּל הַיְּהוּדִים הַנִּמְצְאִים בְּשׁוּשָׁן וְצוּמוּ עָלַי וְאַל תֹּאכְלוּ וְאַל תִּשְׁתּוּ שְׁלֹשֶׁת יָמִים לַיְלָה וָיוֹם, גַּם אֲנִי וְנַעֲרֹתַי אָצוּם כֵּן, וּבְכֵן אָבוֹא אֶל הַמֶּלֶךְ אֲשֶׁר לֹא כַדָּת וְכַאֲשֶׁר אָבַדְתִּי אָבָדְתִּי: וַיַּעֲבֹר מָרְדֳּכַי, וַיַּעַשׂ כְּכֹל אֲשֶׁר צִוְּתָה עָלָיו אֶסְתֵּר:","cond":["megilatEster"]},{"kind":"header","text":"פרק ה'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ה'","cond":["megilatEster"]},{"kind":"text","text":"וַיְהִי בַּיּוֹם הַשְּׁלִישִׁי וַתִּלְבַּשׁ אֶסְתֵּר מַלְכוּת, וַתַּעֲמֹד בַּחֲצַר בֵּית הַמֶּלֶךְ הַפְּנִימִית נֹכַח בֵּית הַמֶּלֶךְ, וְהַמֶּלֶךְ יוֹשֵׁב עַל כִּסֵּא מַלְכוּתוֹ בְּבֵית הַמַּלְכוּת נֹכַח פֶּתַח הַבָּיִת: וַיְהִי כִרְאוֹת הַמֶּלֶךְ אֶת אֶסְתֵּר הַמַּלְכָּה עֹמֶדֶת בֶּחָצֵר נָשְׂאָה חֵן בְּעֵינָיו, וַיּוֹשֶׁט הַמֶּלֶךְ לְאֶסְתֵּר אֶת שַׁרְבִיט הַזָּהָב אֲשֶׁר בְּיָדוֹ, וַתִּקְרַב אֶסְתֵּר וַתִּגַּע בְּרֹאשׁ הַשַּׁרְבִיט: וַיֹּאמֶר לָהּ הַמֶּלֶךְ מַה לָּךְ אֶסְתֵּר הַמַּלְכָּה, וּמַה בַּקָּשָׁתֵךְ עַד חֲצִי הַמַּלְכוּת וְיִנָּתֵן לָךְ: וַתֹּאמֶר אֶסְתֵּר אִם עַל הַמֶּלֶךְ טוֹב, יָבוֹא הַמֶּלֶךְ וְהָמָן הַיּוֹם אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשִׂיתִי לוֹ: וַיֹּאמֶר הַמֶּלֶךְ מַהֲרוּ אֶת הָמָן לַעֲשׂוֹת אֶת דְּבַר אֶסְתֵּר, וַיָּבֹא הַמֶּלֶךְ וְהָמָן אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשְׂתָה אֶסְתֵּר: וַיֹּאמֶר הַמֶּלֶךְ לְאֶסְתֵּר בְּמִשְׁתֵּה הַיַּיִן מַה שְּׁאֵלָתֵךְ וְיִנָּתֵן לָךְ, וּמַה בַּקָּשָׁתֵךְ עַד חֲצִי הַמַּלְכוּת וְתֵעָשׂ: וַתַּעַן אֶסְתֵּר וַתֹּאמַר, שְׁאֵלָתִי וּבַקָּשָׁתִי: אִם מָצָאתִי חֵן בְּעֵינֵי הַמֶּלֶךְ וְאִם עַל הַמֶּלֶךְ טוֹב לָתֵת אֶת שְׁאֵלָתִי וְלַעֲשׂוֹת אֶת בַּקָּשָׁתִי, יָבוֹא הַמֶּלֶךְ וְהָמָן אֶל הַמִּשְׁתֶּה אֲשֶׁר אֶעֱשֶׂה לָהֶם וּמָחָר אֶעֱשֶׂה כִּדְבַר הַמֶּלֶךְ: וַיֵּצֵא הָמָן בַּיּוֹם הַהוּא שָׂמֵחַ וְטוֹב לֵב, וְכִרְאוֹת הָמָן אֶת מָרְדֳּכַי בְּשַׁעַר הַמֶּלֶךְ וְלֹא קָם וְלֹא זָע מִמֶּנּוּ וַיִּמָּלֵא הָמָן עַל מָרְדֳּכַי חֵמָה: וַיִּתְאַפַּק הָמָן וַיָּבוֹא אֶל בֵּיתוֹ, וַיִּשְׁלַח וַיָּבֵא אֶת אֹהֲבָיו וְאֶת זֶרֶשׁ אִשְׁתּוֹ: וַיְסַפֵּר לָהֶם הָמָן אֶת כְּבוֹד עָשְׁרוֹ וְרֹב בָּנָיו, וְאֵת כָּל אֲשֶׁר גִּדְּלוֹ הַמֶּלֶךְ וְאֵת אֲשֶׁר נִשְּׂאוֹ עַל הַשָּׂרִים וְעַבְדֵי הַמֶּלֶךְ: וַיֹּאמֶר הָמָן, אַף לֹא הֵבִיאָה אֶסְתֵּר הַמַּלְכָּה עִם הַמֶּלֶךְ אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשָׂתָה כִּי אִם אוֹתִי, וְגַם לְמָחָר אֲנִי קָרוּא לָהּ עִם הַמֶּלֶךְ: וְכָל זֶה אֵינֶנּוּ שֹׁוֶה לִי, בְּכָל עֵת אֲשֶׁר אֲנִי רֹאֶה אֶת מָרְדֳּכַי הַיְּהוּדִי יוֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ: וַתֹּאמֶר לוֹ זֶרֶשׁ אִשְׁתּוֹ וְכָל אֹהֲבָיו יַעֲשׂוּ עֵץ גָּבֹהַּ חֲמִשִּׁים אַמָּה, וּבַבֹּקֶר אֱמֹר לַמֶּלֶךְ וְיִתְלוּ אֶת מָרְדֳּכַי עָלָיו וּבֹא עִם הַמֶּלֶךְ אֶל הַמִּשְׁתֶּה שָׂמֵחַ, וַיִּיטַב הַדָּבָר לִפְנֵי הָמָן וַיַּעַשׂ הָעֵץ:","cond":["megilatEster"]},{"kind":"header","text":"פרק ו'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ו'","cond":["megilatEster"]},{"kind":"special","text":"בַּלַּיְלָה הַהוּא נָדְדָה שְׁנַת הַמֶּלֶךְ, וַיֹּאמֶר לְהָבִיא אֶת סֵפֶר הַזִּכְרֹנוֹת דִּבְרֵי הַיָּמִים, וַיִּהְיוּ נִקְרָאִים לִפְנֵי הַמֶּלֶךְ:","cond":["megilatEster"]},{"kind":"text","text":"וַיִּמָּצֵא כָתוּב אֲשֶׁר הִגִּיד מָרְדֳּכַי עַל בִּגְתָנָא וָתֶרֶשׁ שְׁנֵי סָרִיסֵי הַמֶּלֶךְ מִשֹּׁמְרֵי הַסַּף אֲשֶׁר בִּקְשׁוּ לִשְׁלֹחַ יָד בַּמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: וַיֹּאמֶר הַמֶּלֶךְ מַה נַּעֲשָׂה יְקָר וּגְדוּלָּה לְמָרְדֳּכַי עַל זֶה, וַיֹּאמְרוּ נַעֲרֵי הַמֶּלֶךְ מְשָׁרְתָיו לֹא נַעֲשָׂה עִמּוֹ דָּבָר: וַיֹּאמֶר הַמֶּלֶךְ מִי בֶחָצֵר, וְהָמָן בָּא לַחֲצַר בֵּית הַמֶּלֶךְ הַחִיצוֹנָה לֵאמֹר לַמֶּלֶךְ לִתְלוֹת אֶת מָרְדֳּכַי עַל הָעֵץ אֲשֶׁר הֵכִין לוֹ: וַיֹּאמְרוּ נַעֲרֵי הַמֶּלֶךְ אֵלָיו הִנֵּה הָמָן עֹמֵד בֶּחָצֵר, וַיֹּאמֶר הַמֶּלֶךְ יָבוֹא: וַיָּבוֹא הָמָן, וַיֹּאמֶר לוֹ הַמֶּלֶךְ מַה לַעֲשׂוֹת בָּאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ, וַיֹּאמֶר הָמָן בְּלִבּוֹ לְמִי יַחְפֹּץ הַמֶּלֶךְ לַעֲשׂוֹת יְקָר יוֹתֵר מִמֶּנִּי: וַיֹּאמֶר הָמָן אֶל הַמֶּלֶךְ, אִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ: יָבִיאוּ לְבוּשׁ מַלְכוּת אֲשֶׁר לָבַשׁ בּוֹ הַמֶּלֶךְ, וְסוּס אֲשֶׁר רָכַב עָלָיו הַמֶּלֶךְ וַאֲשֶׁר נִתַּן כֶּתֶר מַלְכוּת בְּרֹאשׁוֹ: וְנָתוֹן הַלְּבוּשׁ וְהַסּוּס עַל יַד אִישׁ מִשָּׂרֵי הַמֶּלֶךְ הַפַּרְתְּמִים וְהִלְבִּישׁוּ אֶת הָאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ, וְהִרְכִּיבֻהוּ עַל הַסּוּס בִּרְחוֹב הָעִיר וְקָרְאוּ לְפָנָיו כָּכָה יֵעָשֶׂה לָאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ: וַיֹּאמֶר הַמֶּלֶךְ לְהָמָן מַהֵר קַח אֶת הַלְּבוּשׁ וְאֶת הַסּוּס כַּאֲשֶׁר דִּבַּרְתָּ וַעֲשֵׂה כֵן לְמָרְדֳּכַי הַיְּהוּדִי הַיּוֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ, אַל תַּפֵּל דָּבָר מִכֹּל אֲשֶׁר דִּבַּרְתָּ: וַיִּקַּח הָמָן אֶת הַלְּבוּשׁ וְאֶת הַסּוּס וַיַּלְבֵּשׁ אֶת מָרְדֳּכַי, וַיַּרְכִּיבֵהוּ בִּרְחוֹב הָעִיר וַיִּקְרָא לְפָנָיו כָּכָה יֵעָשֶׂה לָאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ: וַיָּשָָב מָרְדֳּכַי אֶל שַׁעַר הַמֶּלֶךְ, וְהָמָן נִדְחַף אֶל בֵּיתוֹ אָבֵל וַחֲפוּי רֹאשׁ: וַיְסַפֵּר הָמָן לְזֶרֶשׁ אִשְׁתּוֹ וּלְכָל אֹהֲבָיו אֵת כָּל אֲשֶׁר קָרָהוּ, וַיֹּאמְרוּ לּוֹ חֲכָמָיו וְזֶרֶשׁ אִשְׁתּוֹ אִם מִזֶּרַע הַיְּהוּדִים מָרְדֳּכַי אֲשֶׁר הַחִלּוֹתָ לִנְפֹּל לְפָנָיו לֹא תוּכַל לוֹ, כִּי נָפוֹל תִּפּוֹל לְפָנָיו: עוֹדָם מְדַבְּרִים עִמּוֹ וְסָרִיסֵי הַמֶּלֶךְ הִגִּיעוּ, וַיַּבְהִלוּ לְהָבִיא אֶת הָמָן אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשְׂתָה אֶסְתֵּר:","cond":["megilatEster"]},{"kind":"header","text":"פרק ז'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ז'","cond":["megilatEster"]},{"kind":"text","text":"וַיָּבֹא הַמֶּלֶךְ וְהָמָן לִשְׁתּוֹת עִם אֶסְתֵּר הַמַּלְכָּה: וַיֹּאמֶר הַמֶּלֶךְ לְאֶסְתֵּר גַּם בַּיּוֹם הַשֵּׁנִי בְּמִשְׁתֵּה הַיַּיִן מַה שְּׁאֵלָתֵךְ אֶסְתֵּר הַמַּלְכָּה וְתִנָּתֵן לָךְ, וּמַה בַּקָּשָׁתֵךְ עַד חֲצִי הַמַּלְכוּת וְתֵעָשׂ: וַתַּעַן אֶסְתֵּר הַמַּלְכָּה וַתֹּאמַר אִם מָצָאתִי חֵן בְּעֵינֶיךָ הַמֶּלֶךְ וְאִם עַל הַמֶּלֶךְ טוֹב, תִּנָּתֶן לִי נַפְשִׁי בִּשְׁאֵלָתִי וְעַמִּי בְּבַקָּשָׁתִי: כִּי נִמְכַּרְנוּ אֲנִי וְעַמִּי לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד, וְאִלּוּ לַעֲבָדִים וְלִשְׁפָחוֹת נִמְכַּרְנוּ הֶחֱרַשְׁתִּי כִּי אֵין הַצָּר שֹׁוֶה בְּנֵזֶק הַמֶּלֶךְ: וַיֹּאמֶר הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ וַיֹּאמֶר לְאֶסְתֵּר הַמַּלְכָּה, מִי הוּא זֶה וְאֵי זֶה הוּא אֲשֶׁר מְלָאוֹ לִבּוֹ לַעֲשׂוֹת כֵּן: וַתֹּאמֶר אֶסְתֵּר אִישׁ צַר וְאוֹיֵב הָמָן הָרָע הַזֶּה, וְהָמָן נִבְעַת מִלִּפְנֵי הַמֶּלֶךְ וְהַמַּלְכָּה: וְהַמֶּלֶךְ קָם בַּחֲמָתוֹ מִמִּשְׁתֵּה הַיַּיִן אֶל גִּנַּת הַבִּיתָן, וְהָמָן עָמַד לְבַקֵּשׁ עַל נַפְשׁוֹ מֵאֶסְתֵּר הַמַּלְכָּה כִּי רָאָה כִּי כָלְתָה אֵלָיו הָרָעָה מֵאֵת הַמֶּלֶךְ: וְהַמֶּלֶךְ שָׁב מִגִּנַּת הַבִּיתָן אֶל בֵּית מִשְׁתֵּה הַיַּיִן וְהָמָן נֹפֵל עַל הַמִּטָּה אֲשֶׁר אֶסְתֵּר עָלֶיהָ, וַיֹּאמֶר הַמֶּלֶךְ הֲגַם לִכְבּוֹשׁ אֶת הַמַּלְכָּה עִמִּי בַּבָּיִת, הַדָּבָר יָצָא מִפִּי הַמֶּלֶךְ וּפְנֵי הָמָן חָפוּ: וַיֹּאמֶר חַרְבוֹנָה אֶחָד מִן הַסָּרִיסִים לִפְנֵי הַמֶּלֶךְ גַּם הִנֵּה הָעֵץ אֲשֶׁר עָשָׂה הָמָן לְמָרְדֳּכַי אֲשֶׁר דִּבֶּר טוֹב עַל הַמֶּלֶךְ עֹמֵד בְּבֵית הָמָן גָּבֹהַּ חֲמִשִּׁים אַמָּה, וַיֹּאמֶר הַמֶּלֶךְ תְּלֻהוּ עָלָיו: וַיִּתְלוּ אֶת הָמָן עַל הָעֵץ אֲשֶׁר הֵכִין לְמָרְדֳּכַי, וַחֲמַת הַמֶּלֶךְ שָׁכָכָה:","cond":["megilatEster"]},{"kind":"header","text":"פרק ח'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ח'","cond":["megilatEster"]},{"kind":"text","text":"בַּיּוֹם הַהוּא נָתַן הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ לְאֶסְתֵּר הַמַּלְכָּה אֶת בֵּית הָמָן צֹרֵר הַיְּהוּדִים, וּמָרְדֳּכַי בָּא לִפְנֵי הַמֶּלֶךְ כִּי הִגִּידָה אֶסְתֵּר מַה הוּא לָהּ: וַיָּסַר הַמֶּלֶךְ אֶת טַבַּעְתּוֹ אֲשֶׁר הֶעֱבִיר מֵהָמָן וַיִּתְּנָהּ לְמָרְדֳּכַי, וַתָּשֶׂם אֶסְתֵּר אֶת מָרְדֳּכַי עַל בֵּית הָמָן: וַתּוֹסֶף אֶסְתֵּר וַתְּדַבֵּר לִפְנֵי הַמֶּלֶךְ וַתִּפֹּל לִפְנֵי רַגְלָיו, וַתֵּבְךְּ וַתִּתְחַנֶּן לוֹ לְהַעֲבִיר אֶת רָעַת הָמָן הָאֲגָגִי וְאֵת מַחֲשַׁבְתּוֹ אֲשֶׁר חָשַׁב עַל הַיְּהוּדִים: וַיּוֹשֶׁט הַמֶּלֶךְ לְאֶסְתֵּר אֵת שַׁרְבִט הַזָּהָב, וַתָּקָם אֶסְתֵּר וַתַּעֲמֹד לִפְנֵי הַמֶּלֶךְ: וַתֹּאמֶר אִם עַל הַמֶּלֶךְ טוֹב וְאִם מָצָאתִי חֵן לְפָנָיו וְכָשֵׁר הַדָּבָר לִפְנֵי הַמֶּלֶךְ וְטוֹבָה אֲנִי בְּעֵינָיו, יִכָּתֵב לְהָשִׁיב אֶת הַסְּפָרִים מַחֲשֶׁבֶת הָמָן בֶּן הַמְּדָתָא הָאֲגָגִי אֲשֶׁר כָּתַב לְאַבֵּד אֶת הַיְּהוּדִים אֲשֶׁר בְּכָל מְדִינוֹת הַמֶּלֶךְ: כִּי אֵיכָכָה אוּכַל וְרָאִיתִי בָּרָעָה אֲשֶׁר יִמְצָא אֶת עַמִּי, וְאֵיכָכָה אוּכַל וְרָאִיתִי בְּאָבְדַן מוֹלַדְתִּי: וַיֹּאמֶר הַמֶּלֶךְ אֲחַשְׁוֵרֹשׁ לְאֶסְתֵּר הַמַּלְכָּה וּלְמָרְדֳּכַי הַיְּהוּדִי, הִנֵּה בֵית הָמָן נָתַתִּי לְאֶסְתֵּר וְאֹתוֹ תָּלוּ עַל הָעֵץ עַל אֲשֶׁר שָׁלַח יָדוֹ בַּיְּהוּדִים: וְאַתֶּם כִּתְבוּ עַל הַיְּהוּדִים כַּטּוֹב בְּעֵינֵיכֶם בְּשֵׁם הַמֶּלֶךְ וְחִתְמוּ בְּטַבַּעַת הַמֶּלֶךְ, כִּי כְתָב אֲשֶׁר נִכְתָּב בְּשֵׁם הַמֶּלֶךְ וְנַחְתּוֹם בְּטַבַּעַת הַמֶּלֶךְ אֵין לְהָשִׁיב: וַיִּקָּרְאוּ סֹפְרֵי הַמֶּלֶךְ בָּעֵת הַהִיא בַּחֹדֶשׁ הַשְּׁלִישִׁי הוּא חֹדֶשׁ סִיוָן בִּשְׁלוֹשָׁה וְעֶשְׂרִים בּוֹ, וַיִּכָּתֵב כְּכָל אֲשֶׁר צִוָּה מָרְדֳּכַי אֶל הַיְּהוּדִים וְאֶל הָאֲחַשְׁדַּרְפְּנִים וְהַפַּחוֹת וְשָׂרֵי הַמְּדִינוֹת אֲשֶׁר מֵהֹדּוּ וְעַד כּוּשׁ, שֶׁבַע וְעֶשְׂרִים וּמֵאָה מְדִינָה, מְדִינָה וּמְדִינָה כִּכְתָבָהּ וְעַם וָעָם כִּלְשֹׁנוֹ, וְאֶל הַיְּהוּדִים כִּכְתָבָם וְכִלְשׁוֹנָם: וַיִּכְתֹּב בְּשֵׁם הַמֶּלֶךְ אֲחַשְׁוֵרֹשׁ וַיַּחְתֹּם בְּטַבַּעַת הַמֶּלֶךְ, וַיִּשְׁלַח סְפָרִים בְּיַד הָרָצִים בַּסּוּסִים רֹכְבֵי הָרֶכֶשׁ הָאֲחַשְׁתְּרָנִים בְּנֵי הָרַמָּכִים: אֲשֶׁר נָתַן הַמֶּלֶךְ לַיְּהוּדִים אֲשֶׁר בְּכָל עִיר וָעִיר לְהִקָּהֵל וְלַעֲמֹד עַל נַפְשָׁם, לְהַשְׁמִיד וְלַהֲרֹג וּלְאַבֵּד אֶת כָּל חֵיל עַם וּמְדִינָה הַצָּרִים אֹתָם טַף וְנָשִׁים, וּשְׁלָלָם לָבוֹז: בְּיוֹם אֶחָד בְּכָל מְדִינוֹת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, בִּשְׁלוֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר: פַּתְשֶׁגֶן הַכְּתָב לְהִנָּתֵן דָּת בְּכָל מְדִינָה וּמְדִינָה גָּלוּי לְכָל הָעַמִּים, וְלִהְיוֹת הַיְּהוּדִים עֲתִידִים לַיּוֹם הַזֶּה לְהִנָּקֵם מֵאֹיְבֵיהֶם: הָרָצִים רֹכְבֵי הָרֶכֶשׁ הָאֲחַשְׁתְּרָנִים יָצְאוּ מְבֹהָלִים וּדְחוּפִים בִּדְבַר הַמֶּלֶךְ, וְהַדָּת נִתְּנָה בְּשׁוּשַׁן הַבִּירָה:","cond":["megilatEster"]},{"kind":"special","text":"וּמָרְדֳּכַי יָצָא מִלִּפְנֵי הַמֶּלֶךְ בִּלְבוּשׁ מַלְכוּת תְּכֵלֶת וָחוּר וַעֲטֶרֶת זָהָב גְּדוֹלָה וְתַכְרִיךְ בּוּץ וְאַרְגָּמָן, וְהָעִיר שׁוּשָׁן צָהֲלָה וְשָׂמֵחָה: לַיְּהוּדִים הָיְתָה אוֹרָה וְשִׂמְחָה, וְשָׂשֹׂן וִיקָר:","cond":["megilatEster"]},{"kind":"text","text":"וּבְכָל מְדִינָה וּמְדִינָה וּבְכָל עִיר וָעִיר, מְקוֹם אֲשֶׁר דְּבַר הַמֶּלֶךְ וְדָתוֹ מַגִּיעַ, שִׂמְחָה וְשָׂשׂוֹן לַיְּהוּדִים מִשְׁתֶּה וְיוֹם טוֹב, וְרַבִּים מֵעַמֵּי הָאָרֶץ מִתְיַהֲדִים כִּי נָפַל פַּחַד הַיְּהוּדִים עֲלֵיהֶם:","cond":["megilatEster"]},{"kind":"header","text":"פרק ט'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ט'","cond":["megilatEster"]},{"kind":"text","text":"וּבִשְׁנֵים עָשָׂר חֹדֶשׁ הוּא חֹדֶשׁ אֲדָר בִּשְׁלוֹשָׁה עָשָׂר יוֹם בּוֹ אֲשֶׁר הִגִּיעַ דְּבַר הַמֶּלֶךְ וְדָתוֹ לְהֵעָשׂוֹת, בַּיּוֹם אֲשֶׁר שִׂבְּרוּ אֹיְבֵי הַיְּהוּדִים לִשְׁלוֹט בָּהֶם וְנַהֲפוֹךְ הוּא אֲשֶׁר יִשְׁלְטוּ הַיְּהוּדִים הֵמָּה בְּשֹׂנְאֵיהֶם: נִקְהֲלוּ הַיְּהוּדִים בְּעָרֵיהֶם בְּכָל מְדִינוֹת הַמֶּלֶךְ אֳחַשְׁוֵרוֹשׁ לִשְׁלֹחַ יָד בִּמְבַקְשֵׁי רָעָתָם, וְאִישׁ לֹא עָמַד לִפְנֵיהֶם כִּי נָפַל פַּחְדָּם עַל כָּל הָעַמִּים: וְכָל שָׂרֵי הַמְּדִינוֹת וְהָאֲחַשְׁדַּרְפְּנִים וְהַפַּחוֹת וְעֹשֵׂי הַמְּלָאכָה אֲשֶׁר לַמֶּלֶךְ מְנַשְּׂאִים אֶת הַיְּהוּדִים, כִּי נָפַל פַּחַד מָרְדֳּכַי עֲלֵיהֶם: כִּי גָדוֹל מָרְדֳּכַי בְּבֵית הַמֶּלֶךְ וְשָׁמְעוֹ הוֹלֵךְ בְּכָל הַמְּדִינוֹת, כִּי הָאִישׁ מָרְדֳּכַי הוֹלֵךְ וְגָדוֹל: וַיַּכּוּ הַיְּהוּדִים בְּכָל אֹיְבֵיהֶם מַכַּת חֶרֶב וְהֶרֶג וְאַבְדָן, וַיַּעֲשׂוּ בְשֹׂנְאֵיהֶם כִּרְצוֹנָם: וּבְשׁוּשַׁן הַבִּירָה הָרְגוּ הַיְּהוּדִים וְאַבֵּד חֲמֵשׁ מֵאוֹת אִישׁ: וְאֵת פַּרְשַׁנְדָּתָא וְאֵת דַּלְפוֹן וְאֵת אַסְפָּתָא: וְאֵת פּוֹרָתָא וְאֵת אֲדַלְיָא וְאֵת אֲרִידָתָא: וְאֵת פַּרְמַשְׁתָּא וְאֵת אֲרִיסַי וְאֵת אֲרִדַי וְאֵת וַיְזָתָא: עֲשֶׂרֶת בְּנֵי הָמָן בֶּן הַמְּדָתָא צֹרֵר הַיְּהוּדִים הָרָגוּ, וּבַבִּזָּה לֹא שָׁלְחוּ אֶת יָדָם: בַּיּוֹם הַהוּא בָּא מִסְפַּר הַהֲרוּגִים בְּשׁוּשַׁן הַבִּירָה לִפְנֵי הַמֶּלֶךְ: וַיֹּאמֶר הַמֶּלֶךְ לְאֶסְתֵּר הַמַּלְכָּה בְּשׁוּשַׁן הַבִּירָה הָרְגוּ הַיְּהוּדִים וְאַבֵּד חֲמֵשׁ מֵאוֹת אִישׁ וְאֵת עֲשֶׂרֶת בְּנֵי הָמָן, בִּשְׁאָר מְדִינוֹת הַמֶּלֶךְ מֶה עָשׂוּ, וּמַה שְּׁאֵלָתֵךְ וְיִנָּתֵן לָךְ וּמַה בַּקָּשָׁתֵךְ עוֹד וְתֵעָשׂ: וַתֹּאמֶר אֶסְתֵּר אִם עַל הַמֶּלֶךְ טוֹב, יִנָּתֵן גַּם מָחָר לַיְּהוּדִים אֲשֶׁר בְּשׁוּשָׁן לַעֲשׂוֹת כְּדָת הַיּוֹם, וְאֵת עֲשֶׂרֶת בְּנֵי הָמָן יִתְלוּ עַל הָעֵץ: וַיֹּאמֶר הַמֶּלֶךְ לְהֵעָשׂוֹת כֵּן וַתִּנָּתֵן דָּת בְּשׁוּשָׁן, וְאֵת עֲשֶׂרֶת בְּנֵי הָמָן תָּלוּ: וַיִּקָּהֲלוּ הַיְּהוּדִים אֲשֶׁר בְּשׁוּשָׁן גַּם בְּיוֹם אַרְבָּעָה עָשָׂר לְחֹדֶשׁ אֲדָר וַיַּהַרְגוּ בְשׁוּשָׁן שְׁלֹשׁ מֵאוֹת אִישׁ, וּבַבִּזָּה לֹא שָׁלְחוּ אֶת יָדָם: וּשְׁאָר הַיְּהוּדִים אֲשֶׁר בִּמְדִינוֹת הַמֶּלֶךְ נִקְהֲלוּ וְעָמֹד עַל נַפְשָׁם וְנוֹחַ מֵאֹיְבֵיהֶם וְהָרֹג בְּשֹׂנְאֵיהֶם חֲמִשָּׁה וְשִׁבְעִים אָלֶף, וּבַבִּזָּה לֹא שָׁלְחוּ אֶת יָדָם: בְּיוֹם שְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ אֲדָר, וְנוֹחַ בְּאַרְבָּעָה עָשָׂר בּוֹ וְעָשֹׂה אֹתוֹ יוֹם מִשְׁתֶּה וְשִׂמְחָה: וְהַיְּהוּדִים אֲשֶׁר בְּשׁוּשָׁן נִקְהֲלוּ בִּשְׁלֹשָׁה עָשָׂר בּוֹ וּבְאַרְבָּעָה עָשָׂר בּוֹ, וְנוֹחַ בַּחֲמִשָּׁה עָשָׂר בּוֹ וְעָשֹׂה אֹתוֹ יוֹם מִשְׁתֶּה וְשִׂמְחָה: עַל כֵּן הַיְּהוּדִים הַפְּרָזִים הַיֹּשְׁבִים בְּעָרֵי הַפְּרָזוֹת, עֹשִׂים אֵת יוֹם אַרְבָּעָה עָשָׂר לְחֹדֶשׁ אֲדָר שִׂמְחָה וּמִשְׁתֶּה וְיוֹם טוֹב, וּמִשְׁלוֹחַ מָנוֹת אִישׁ לְרֵעֵהוּ: וַיִּכְתֹּב מָרְדֳּכַי אֶת הַדְּבָרִים הָאֵלֶּה, וַיִּשְׁלַח סְפָרִים אֶל כָּל הַיְּהוּדִים אֲשֶׁר בְּכָל מְדִינוֹת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ הַקְּרוֹבִים וְהָרְחוֹקִים: לְקַיֵּם עֲלֵיהֶם, לִהְיוֹת עֹשִׂים אֵת יוֹם אַרְבָּעָה עָשָׂר לְחֹדֶשׁ אֲדָר וְאֵת יוֹם חֲמִשָּׁה עָשָׂר בּוֹ, בְּכָל שָׁנָה וְשָׁנָה: כַּיָּמִים אֲשֶׁר נָחוּ בָהֶם הַיְּהוּדִים מֵאוֹיְבֵיהֶם, וְהַחֹדֶשׁ אֲשֶׁר נֶהְפַּךְ לָהֶם מִיָּגוֹן לְשִׂמְחָה וּמֵאֵבֶל לְיוֹם טוֹב, לַעֲשׂוֹת אוֹתָם יְמֵי מִשְׁתֶּה וְשִׂמְחָה וּמִשְׁלוֹחַ מָנוֹת אִישׁ לְרֵעֵהוּ וּמַתָּנוֹת לָאֶבְיוֹנִים: וְקִבֵּל הַיְּהוּדִים אֵת אֲשֶׁר הֵחֵלּוּ לַעֲשׂוֹת, וְאֵת אֲשֶׁר כָּתַב מָרְדֳּכַי אֲלֵיהֶם: כִּי הָמָן בֶּן הַמְּדָתָא הָאֲגָגִי צֹרֵר כָּל הַיְּהוּדִים חָשַׁב עַל הַיְּהוּדִים לְאַבְּדָם, וְהִפִּיל פּוּר הוּא הַגּוֹרָל לְהֻמָּם וּלְאַבְּדָם: וּבְבֹאָהּ לִפְנֵי הַמֶּלֶךְ, אָמַר עִם הַסֵּפֶר יָשׁוּב מַחֲשַׁבְתּוֹ הָרָעָה אֲשֶׁר חָשַׁב עַל הַיְּהוּדִים עַל רֹאשׁוֹ, וְתָלוּ אֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ: עַל כֵּן קָרְאוּ לַיָּמִים הָאֵלֶּה פוּרִים עַל שֵׁם הַפּוּר, עַל כֵּן עַל כָּל דִּבְרֵי הָאִגֶּרֶת הַזֹּאת, וּמָה רָאוּ עַל כָּכָה וּמָה הִגִּיעַ אֲלֵיהֶם: קִיְּמוּ וְקִבְּלוּ הַיְּהוּדִים עֲלֵיהֶם וְעַל זַרְעָם וְעַל כָּל הַנִּלְוִים עֲלֵיהֶם וְלֹא יַעֲבוֹר, לִהְיוֹת עֹשִׂים אֵת שְׁנֵי הַיָּמִים הָאֵלֶּה כִּכְתָבָם וְכִזְמַנָּם, בְּכָל שָׁנָה וְשָׁנָה: וְהַיָּמִים הָאֵלֶּה נִזְכָּרִים וְנַעֲשִׂים בְּכָל דּוֹר וָדוֹר מִשְׁפָּחָה וּמִשְׁפָּחָה מְדִינָה וּמְדִינָה וְעִיר וָעִיר, וִימֵי הַפּוּרִים הָאֵלֶּה לֹא יַעַבְרוּ מִתּוֹךְ הַיְּהוּדִים וְזִכְרָם לֹא יָסוּף מִזַּרְעָם: וַתִּכְתֹּב אֶסְתֵּר הַמַּלְכָּה בַת אֲבִיחַיִל וּמָרְדֳּכַי הַיְּהוּדִי אֶת כָּל תֹּקֶף, לְקַיֵּם אֵת אִגֶּרֶת הַפּוּרִים הַזֹּאת הַשֵּׁנִית: וַיִּשְׁלַח סְפָרִים אֶל כָּל הַיְּהוּדִים, אֶל שֶׁבַע וְעֶשְׂרִים וּמֵאָה מְדִינָה מַלְכוּת אֲחַשְׁוֵרוֹשׁ, דִּבְרֵי שָׁלוֹם וֶאֱמֶת: לְקַיֵּם אֵת יְמֵי הַפֻּרִים הָאֵלֶּה בִּזְמַנֵּיהֶם כַּאֲשֶׁר קִיַּם עֲלֵיהֶם מָרְדֳּכַי הַיְּהוּדִי וְאֶסְתֵּר הַמַּלְכָּה וְכַאֲשֶׁר קִיְּמוּ עַל נַפְשָׁם וְעַל זַרְעָם, דִּבְרֵי הַצֹּמוֹת וְזַעֲקָתָם: וּמַאֲמַר אֶסְתֵּר קִיַּם דִּבְרֵי הַפֻּרִים הָאֵלֶּה, וְנִכְתָּב בַּסֵּפֶר:","cond":["megilatEster"]},{"kind":"header","text":"פרק י'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק י'","cond":["megilatEster"]},{"kind":"text","text":"וַיָּשֶׂם הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ מַס עַל הָאָרֶץ וְאִיֵּי הַיָּם: וְכָל מַעֲשֵׂה תָקְפּוֹ וּגְבוּרָתוֹ, וּפָרָשַׁת גְּדֻלַּת מָרְדֳּכַי אֲשֶׁר גִּדְּלוֹ הַמֶּלֶךְ, הֲלוֹא הֵם כְּתוּבִים עַל סֵפֶר דִּבְרֵי הַיָּמִים לְמַלְכֵי מָדַי וּפָרָס:","cond":["megilatEster"]},{"kind":"special","text":"כִּי מָרְדֳּכַי הַיְּהוּדִי מִשְׁנֶה לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ וְגָדוֹל לַיְּהוּדִים וְרָצוּי לְרֹב אֶחָיו, דֹּרֵשׁ טוֹב לְעַמּוֹ וְדֹבֵר שָׁלוֹם לְכָל זַרְעוֹ:","cond":["megilatEster"]},{"kind":"header","text":"ברכת הרב את ריבנו","cond":["megilatEster"]},{"kind":"instruction","text":"ברכת הרב את ריבנו מברכים גם ביום וגם בלילה, ומברכים אותה רק בציבור של עשרה. ברכה זו מברך רק החזן הקורא את המגילה לאחר שכרך את כל המגילה.","cond":["megilatEster"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הָרָב אֶת רִיבֵנוּ, וְהַדָּן אֶת דִּינֵנוּ, וְהַנּוֹקֵם אֶת נִקְמָתֵנוּ, וְהַמְשַׁלֵּם גְּמוּל לְכָל אוֹיְבֵי נַפְשֵׁנוּ, וְהַנִּפְרָע לָנוּ מִצָּרֵינוּ. בָּרוּךְ אַתָּה יהוה, הַנִּפְרָע לְעַמּוֹ יִשְׂרָאֵל מִכָּל צָרֵיהֶם, הָאֵל הַמּוֹשִׁיעַ.","cond":["megilatEster"]},{"kind":"header","text":"אשר הניא","cond":["megilatEster"]},{"kind":"instruction","text":"אשר הניא\n\nבשחרית מתחילים משושנת יעקב. ויש נוהגים לומר \"אשר הניא\" אף בשחרית, אם אין אומרים פיוטים בחזרת הש\"ץ.","cond":["megilatEster"]},{"kind":"text","text":"אֲשֶׁר הֵנִיא עֲצַת גּוֹיִם, וַיָּפֶר מַחְשְׁבוֹת עֲרוּמִים.\nבְּקוּם עָלֵינוּ אָדָם רָשָׁע, נֵצֶר זָדוֹן מִזֶּרַע עֲמָלֵק.\nגָּאָה בְעָשְׁרוֹ וְכָרָה לוֹ בּוֹר, וּגְדֻלָּתוֹ יָקְשָׁה לּוֹ לָכֶד.\nדִּמָּה בְנַפְשׁוֹ לִלְכֹּד וְנִלְכַּד, בִּקֵּשׁ לְהַשְׁמִיד וְנִשְׁמַד מְהֵרָה.\nהָמָן הוֹדִיעַ אֵיבַת אֲבוֹתָיו, וְעוֹרֵר שִׂנְאַת אַחִים לַבָּנִים.\nוְלֹא זָכַר רַחֲמֵי שָׁאוּל, כִּי בְחֶמְלָתוֹ עַל אֲגָג נוֹלַד אוֹיֵב.\nזָמַם רָשָׁע לְהַכְרִית צַדִּיק, וְנִלְכַּד טָמֵא בִּידֵי טָהוֹר.\nחֶסֶד גָּבַר עַל שִׁגְגַת אָב, וְרָשָׁע הוֹסִיף חֵטְא עַל חֲטָאָיו.\nטָמַן בְּלִבּוֹ מַחְשְׁבוֹת עֲרוּמָיו, וַיִּתְמַכֵּר לַעֲשׂוֹת רָעָה.\nיָדוֹ שָׁלַח בִּקְדוֹשֵׁי אֵל, כַּסְפּוֹ נָתַן לְהַכְרִית זִכְרָם.\nכִּרְאוֹת מָרְדֳּכַי כִּי יָצָא קֶצֶף, וְדָתֵי הָמָן נִתְּנוּ בְשׁוּשָׁן.\nלָבַשׁ שַׂק וְקָשַׁר מִסְפֵּד, וְגָזַר צוֹם וַיֵּשֶׁב עַל הָאֵפֶר.\nמִי זֶה יַעֲמֹד לְכַפֵּר שְׁגָגָה, וְלִמְחֹל חַטַּאת עֲוׂן אֲבוֹתֵינוּ.\nנֵץ פָּרַח מִלּוּלָב, הֵן הֲדַסָּה עָמְדָה לְעוֹרֵר יְשֵׁנִים.\nסָרִיסֶיהָ הִבְהִילוּ לְהָמָן, לְהַשְׁקוֹתוֹ יֵין חֲמַת תַּנִּינִים.\nעָמַד בְּעָשְׁרוֹ וְנָפַל בְּרִשְׁעוֹ, עָשָׂה לוֹ עֵץ וְנִתְלָה עָלָיו.\nפִּיהֶם פָּתְחוּ כָָּל יוֹשְׁבֵי תֵבֵל, כִּי פוּר הָמָן נֶהְפַּךְ לְפוּרֵנוּ.\nצַדִּיק נֶחֱלַץ מִיַּד רָשָׁע, אוֹיֵב נִתַּן תַּחַת נַפְשׁוֹ.\nקִיְּמוּ עֲלֵיהֶם לַעֲשׂוֹת פּוּרִים, וְלִשְׂמֹחַ בְּכָל שָׁנָה וְשָׁנָה.\nרָאִיתָ אֶת תְּפִלַּת מָרְדֳּכַי וְאֶסְתֵּר, הָמָן וּבָנָיו עַל הָעֵץ תָּלִיתָ.","cond":["megilatEster"]},{"kind":"header","text":"שושנת יעקב","cond":["megilatEster"]},{"kind":"text","text":"שׁוֹשַׁנַּת יַעֲקֹב צָהֲלָה וְשָׂמֵחָה, בִּרְאוֹתָם יַחַד תְּכֵלֶת מָרְדֳּכָי.\nתְּשׁוּעָתָם הָיִיתָ לָנֶצַח, וְתִקְוָתָם בְּכָל דּוֹר וָדוֹר.\nלְהוֹדִיעַ שֶׁכָּל קֹוֶיךָ לֹא יֵבֹשׁוּ, וְלֹא יִכָּלְמוּ לָנֶצַח כָּל הַחוֹסִים בָּךְ.\nאָרוּר הָמָן אֲשֶׁר בִּקֵשׁ לְאַבְּדִי. בָּרוּךְ מָרְדֳּכַי הַיְּהוּדִי.\nאֲרוּרָה זֶרֶשׁ אֵשֶׁת מַפְחִידִי. בְּרוּכָה אֶסְתֵּר [מְגִנָּה] בַּעֲדִי.\nאֲרוּרִים כָּל הָרְשָׁעִים. בְּרוּכִים כָּל הַצַּדִּיקִים.\nוְגַם חַרְבוֹנָה זָכוּר לַטּוֹב.","cond":["megilatEster"]},{"kind":"header","text":"אשרי ובא לציון","cond":[]},{"kind":"text","text":"אַשְׁרֵי יוֹשְׁבֵי בֵיתֶךָ עוֹד יְהַלְלוּךָ סֶּלָה:\nאַשְׁרֵי הָעָם שֶׁכָּכָה לּוֹ אַשְׁרֵי הָעָם שֶׁיהוה אֱלֹהָיו:\nתְּהִלָּה לְדָוִד, אֲרוֹמִמְךָ אֱלוֹהַי הַמֶּלֶךְ וַאֲבָרְכָה שִׁמְךָ לְעוֹלָם וָעֶד:\nבְּכָל יוֹם אֲבָרְכֶךָּ וַאֲהַלְלָה שִׁמְךָ לְעוֹלָם וָעֶד:\nגָּדוֹל יהוה וּמְהֻלָּל מְאֹד וְלִגְדֻלָּתוֹ אֵין חֵקֶר:\nדּוֹר לְדוֹר יְשַׁבַּח מַעֲשֶׂיךָ וּגְבוּרֹתֶיךָ יַגִּידוּ:\nהֲדַר כְּבוֹד הוֹדֶךָ וְדִבְרֵי נִפְלְאוֹתֶיךָ אָשִׂיחָה:\nוֶעֱזוּז נוֹרְאֹתֶיךָ יֹאמֵרוּ וּגְדוּלָּתְךָ אֲסַפְּרֶנָּה:\nזֵכֶר רַב טוּבְךָ יַבִּיעוּ וְצִדְקָתְךָ יְרַנֵּנוּ:","cond":[]},{"kind":"text","text":"חַנּוּן וְרַחוּם יהוה אֶרֶךְ אַפַּיִם וּגְדָל חָסֶד:\nטוֹב יהוה לַכֹּל וְרַחֲמָיו עַל כָּל מַעֲשָׂיו:\nיוֹדוּךָ יהוה כָּל מַעֲשֶׂיךָ וַחֲסִידֶיךָ יְבָרְכוּכָה:\nכְּבוֹד מַלְכוּתְךָ יֹאמֵרוּ וּגְבוּרָתְךָ יְדַבֵּרוּ:\nלְהוֹדִיעַ לִבְנֵי הָאָדָם גְּבוּרֹתָיו וּכְבוֹד הֲדַר מַלְכוּתוֹ:\nמַלְכוּתְךָ מַלְכוּת כָּל עֹלָמִים וּמֶמְשַׁלְתְּךָ בְּכָל דּוֹר וָדוֹר:\nסוֹמֵךְ יהוה לְכָל הַנֹּפְלִים וְזוֹקֵף לְכָל הַכְּפוּפִים:\nעֵינֵי כֹל אֵלֶיךָ יְשַׂבֵּרוּ וְאַתָּה נוֹתֵן לָהֶם אֶת אָכְלָם בְּעִתּוֹ:","cond":[]},{"kind":"text","text":"פּוֹתֵחַ אֶת יָדֶךָ וּמַשְׂבִּיעַ לְכָל חַי רָצוֹן:\nצַדִּיק יהוה בְּכָל דְּרָכָיו וְחָסִיד בְּכָל מַעֲשָׂיו:\nקָרוֹב יהוה לְכָל קֹרְאָיו לְכֹל אֲשֶׁר יִקְרָאֻהוּ בֶאֱמֶת:\nרְצוֹן יְרֵאָיו יַעֲשֶׂה וְאֶת שַׁוְעָתָם יִשְׁמַע וְיוֹשִׁיעֵם:\nשׁוֹמֵר יהוה אֶת כָּל אֹהֲבָיו וְאֵת כָּל הָרְשָׁעִים יַשְׁמִיד:\nתְּהִלַּת יהוה יְדַבֶּר פִּי וִיבָרֵךְ כָּל בָּשָׂר שֵׁם קָדְשׁוֹ לְעוֹלָם וָעֶד:\nוַאֲנַחְנוּ נְבָרֵךְ יָהּ מֵעַתָּה וְעַד עוֹלָם הַלְלוּיָהּ:","cond":[]},{"kind":"text","text":"לַמְנַצֵּחַ מִזְמוֹר לְדָוִד: יַעַנְךָ יהוה בְּיוֹם צָרָה, יְשַׂגֶּבְךָ שֵׁם אֱלֹהֵי יַעֲקֹב: יִשְׁלַח עֶזְרְךָ מִקֹּדֶשׁ, וּמִצִּיּוֹן יִסְעָדֶךָּ: יִזְכֹּר כָּל מִנְחֹתֶךָ, וְעוֹלָתְךָ יְדַשְּׁנֶה סֶלָה: יִתֶּן לְךָ כִלְבָבֶךָ, וְכָל עֲצָתְךָ יְמַלֵּא: נְרַנְּנָה בִּישׁוּעָתֶךָ וּבְשֵׁם אֱלֹהֵינוּ נִדְגֹּל, יְמַלֵּא יהוה כָּל מִשְׁאֲלוֹתֶיךָ: עַתָּה יָדַעְתִּי כִּי הוֹשִׁיעַ יהוה מְשִׁיחוֹ, יַעֲנֵהוּ מִשְּׁמֵי קָדְשׁוֹ, בִּגְבֻרוֹת יֵשַׁע יְמִינוֹ: אֵלֶּה בָרֶכֶב וְאֵלֶּה בַסּוּסִים, וַאֲנַחְנוּ בְּשֵׁם יהוה אֱלֹהֵינוּ נַזְכִּיר: הֵמָּה כָּרְעוּ וְנָפָלוּ, וַאֲנַחְנוּ קַּמְנוּ וַנִּתְעוֹדָד: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":["lamnatzeach"]},{"kind":"text","text":"וּבָא לְצִיּוֹן גּוֹאֵל, וּלְשָׁבֵי פֶשַׁע בְּיַעֲקֹב, נְאֻם יהוה:","cond":[]},{"kind":"text","text":"וַאֲנִי זֹאת בְּרִיתִי אוֹתָם, אָמַר יהוה, רוּחִי אֲשֶׁר עָלֶיךָ וּדְבָרַי אֲשֶׁר שַׂמְתִּי בְּפִיךָ, לֹא יָמוּשׁוּ מִפִּיךָ וּמִפִּי זַרְעֲךָ וּמִפִּי זֶרַע זַרְעֲךָ, אָמַר יהוה, מֵעַתָּה וְעַד עוֹלָם:","cond":["noTishaaBeav"]},{"kind":"header","text":"ואתה קדוש","cond":[]},{"kind":"text","text":"וְאַתָּה קָדוֹשׁ יוֹשֵׁב תְּהִלּוֹת יִשְׂרָאֵל: וְקָרָא זֶה אֶל זֶה וְאָמַר: קָדוֹשׁ, קָדוֹשׁ, קָדוֹשׁ יהוה צְבָאוֹת, מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ: וּמְקַבְּלִין דֵּין מִן דֵּין וְאָמְרִין: קַדִּישׁ בִּשְׁמֵי מֵרוֹמַא עִלָאַה בֵּית שְׁכִינְתֵּהּ, קַדִּישׁ עַל אַרְעָא עוֹבַד גְּבוּרְתֵּהּ, קַדִּישׁ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא, יהוה צְבָאוֹת מַלְיָא כָל אַרְעָא זִיו יְקָרֵהּ. וַתִּשָּׂאֵנִי רוּחַ, וָאֶשְׁמַע אַחֲרַי קוֹל רַעַשׁ גָּדוֹל: בָּרוּךְ כְּבוֹד יהוה מִמְּקוֹמוֹ: וּנְטָלַתְנִי רוּחָא, וּשְׁמָעִית בַּתְרַי קַל זִיעַ שַׂגִּיא דִמְשַׁבְּחִין וְאָמְרִין: בְּרִיךְ יְקָרָא דַיהוה מֵאֲתָר בֵּית שְׁכִינְתֵּהּ. יהוה יִמְלֹךְ לְעוֹלָם וָעֶד: יהוה מַלְכוּתֵיהּ קָאֵים לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\n\nיהוה אֱלֹהֵי אַבְרָהָם יִצְחָק וְיִשְׂרָאֵל אֲבוֹתֵינוּ, שָׁמְרָה זֹּאת לְעוֹלָם, לְיֵצֶר מַחְשְׁבוֹת לְבַב עַמֶּךָ, וְהָכֵן לְבָבָם אֵלֶיךָ: וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית, וְהִרְבָּה לְהָשִׁיב אַפּוֹ, וְלֹא יָעִיר כָּל חֲמָתוֹ: כִּי אַתָּה יהוה טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קוֹרְאֶיךָ: צִדְקָתְךָ צֶּדֶק לְעוֹלָם, וְתוֹרָתְךָ אֱמֶת: תִּתֵּן אֱמֶת לְיַעֲקֹב, חֶסֶד לְאַבְרָהָם, אֲשֶׁר נִשְׁבַּעְתָּ לַאֲבֹתֵינוּ מִימֵי קֶדֶם: בָּרוּךְ אֲדֹנָי יוֹם יוֹם, יַעֲמָס לָנוּ הָאֵל יְשׁוּעָתֵנוּ, סֶלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב, סֶלָה: יהוה צְבָאוֹת אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ: בָּרוּךְ הוּא אֱלֹהֵינוּ שֶׁבְּרָאָנוּ לִכְבוֹדוֹ, וְהִבְדִּילָנוּ מִן הַתּוֹעִים, וְנָתַן לָנוּ תּוֹרַת אֱמֶת, וְחַיֵּי עוֹלָם נָטַע בְּתוֹכֵנוּ. הוּא יִפְתַּח לִבֵּנוּ בְּתוֹרָתוֹ, וְיָשֵׂם בְּלִבֵּנוּ אַהֲבָתוֹ וְיִרְאָתוֹ וְלַעֲשׂוֹת רְצוֹנוֹ וּלְעָבְדוֹ בְּלֵבָב שָׁלֵם. לְמַעַן לֹא נִיגַע לָרִיק, וְלֹא נֵלֵד לַבֶּהָלָה. יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁנִּשְׁמֹר חֻקֶּיךָ בָּעוֹלָם הַזֶּה, וְנִזְכֶּה וְנִחְיֶה וְנִרְאֶה וְנִירַשׁ טוֹבָה וּבְרָכָה לִשְׁנֵי יְמוֹת הַמָּשִׁיחַ וּלְחַיֵּי הָעוֹלָם הַבָּא. לְמַעַן יְזַמֶּרְךָ כָבוֹד וְלֹא יִדֹּם, יהוה אֱלֹהַי לְעוֹלָם אוֹדֶךָּ: בָּרוּךְ הַגֶּבֶר אֲשֶׁר יִבְטַח בַּיהוה, וְהָיָה יהוה מִבְטַחוֹ: בִּטְחוּ בַיהוה עֲדֵי עַד, כִּי בְּיָהּ יהוה צוּר עוֹלָמִים: וְיִבְטְחוּ בְךָ יוֹדְעֵי שְׁמֶךָ, כִּי לֹא עָזַבְתָּ דֹּרְשֶׁיךָ יהוה: יהוה חָפֵץ לְמַעַן צִדְקוֹ, יַגְדִּיל תּורָה וְיַאְדִּיר: יהוה אֲדֹנֵינוּ, מָה אַדִּיר שִׁמְךָ בְּכָל הָאָרֶץ: חִזְקוּ וְיַאֲמֵץ לְבַבְכֶם כָּל הַמְיַחֲלִים לַיהוה:","cond":[]},{"kind":"text","text":"וְעַתָּה יִגְדַל נָא כֹּחַ אֲדֹנָי כַּאֲשֶׁר דִבַּרְתָּ לֵאמֹר: זְכֹר רַחֲמֶיךָ יהוה וַחֲסָדֶיךָ כִּי מֵעוֹלָם הֵמָּה:","cond":[]},{"kind":"instruction","text":"קדיש תתקבל","cond":["noMusaf"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":["noMusaf"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noMusaf","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noMusaf","ayt"]},{"kind":"text","text":"תִּתְקַבַּל צְלוֹתְהוֹן וּבָעוּתְהוֹן דְּכָל בֵּית יִשְׂרָאֵל קֳדָם אֲבוּהוֹן דִּי בִשְׁמַיָּא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":["noMusaf"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noMusaf","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noMusaf","ayt"]},{"kind":"header","text":"הכנסת ספר תורה","cond":["tora"]},{"kind":"instruction","text":"הכנסת ספר תורה","cond":["tora"]},{"kind":"text","text":"יְהַלְלוּ אֶת שֵׁם יהוה, כִּי נִשְׂגָּב שְׁמוֹ לְבַדּוֹ.\nוהקהל אומרים - הוֹדוֹ עַל אֶרֶץ וְשָׁמָיִם: וַיָּרֶם קֶרֶן לְעַמּוֹ, תְּהִלָּה לְכָל חֲסִידָיו, לִבְנֵי יִשְׂרָאֵל עַם קְרוֹבוֹ, הַלְלוּיָהּ:\n\nלְדָוִד מִזְמוֹר, לַיהוה הָאָרֶץ וּמְלוֹאָהּ, תֵּבֵל וְיֹשְׁבֵי בָהּ: כִּי הוּא עַל יַמִּים יְסָדָהּ, וְעַל נְהָרוֹת יְכוֹנְנֶהָ: מִי יַעֲלֶה בְהַר יהוה, וּמִי יָקוּם בִּמְקוֹם קָדְשׁוֹ: נְקִי כַפַּיִם וּבַר לֵבָב, אֲשֶׁר לֹא נָשָׂא לַשָּׁוְא נַפְשִׁי וְלֹא נִשְׁבַּע לְמִרְמָה: יִשָּׂא בְרָכָה מֵאֵת יהוה, וּצְדָקָה מֵאֱלֹהֵי יִשְׁעוֹ: זֶה דּוֹר דֹּרְשָׁיו, מְבַקְשֵׁי פָנֶיךָ יַעֲקֹב סֶלָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וְהִנָּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבוֹא מֶלֶךְ הַכָּבוֹד: מִי זֶה מֶלֶךְ הַכָּבוֹד, יהוה עִזּוּז וְגִבּוֹר, יהוה גִּבּוֹר מִלְחָמָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבֹא מֶלֶךְ הַכָּבוֹד: מִי הוּא זֶה מֶלֶךְ הַכָּבוֹד, יהוה צְבָאוֹת הוּא מֶלֶךְ הַכָּבוֹד סֶלָה:","cond":["tora"]},{"kind":"instruction","text":"כשמכניסים את הספר אומרים","cond":["tora"]},{"kind":"text","text":"וּבְנֻחֹה יֹאמַר: שׁוּבָה יהוה רִבְבוֹת אַלְפֵי יִשְׂרָאֵל: קוּמָה יהוה לִמְנוּחָתֶךָ, אַתָּה וַאֲרוֹן עֻזֶּךָ: כֹּהֲנֶיךָ יִלְבְּשׁוּ צֶדֶק, וַחֲסִידֶיךָ יְרַנֵּנוּ: בַּעֲבוּר דָּוִד עַבְדֶּךָ אַל תָּשֵׁב פְּנֵי מְשִׁיחֶךָ: כִּי לֶקַח טוֹב נָתַתִּי לָכֶם, תּוֹרָתִי אַל תַּעֲזֹבוּ: עֵץ חַיִּים הִיא לַמַּחֲזִיקִים בָּהּ, וְתֹמְכֶיהָ מְאֻשָּׁר: דְּרָכֶיהָ דַרְכֵי נֹעַם וְכָל נְתִיבוֹתֶיהָ שָׁלוֹם: הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם:","cond":["tora"]},{"kind":"instruction","text":"חצי קדיש","cond":["musaf"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":["musaf"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["musaf","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["musaf","ayt"]},{"kind":"header","text":"מוסף","cond":["musaf"]},{"kind":"instruction","text":"לפני תפילת העמידה חולצים את התפילין.","cond":["musaf","rh"]},{"kind":"instruction","text":"תפילת העמידה","cond":["musaf"]},{"kind":"text","text":"כִּי שֵׁם יהוה אֶקְרָא, הָבוּ גֹדֶל לֵאלֹהֵינוּ:\nאֲדֹנָי, שְׂפָתַי תִּפְתָּח, וּפִי יַגִּיד תְּהִלָּתֶךָ:","cond":["musaf"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק, וֵאלֹהֵי יַעֲקֹב, הָאֵל הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, וְקוֹנֵה הַכֹּל, וְזוֹכֵר חַסְדֵי אָבוֹת, וּמֵבִיא גוֹאֵל לִבְנֵי בְנֵיהֶם לְמַעַן שְׁמוֹ בְּאַהֲבָה.","cond":["musaf"]},{"kind":"special","text":"זָכְרֵנוּ לְחַיִּים, מֶלֶךְ חָפֵץ בַּחַיִּים, וְכָתְבֵנוּ בְּסֵפֶר הַחַיִּים, לְמַעַנְךָ אֱלֹהִים חַיִּים.","cond":["musaf","ayt"]},{"kind":"text","text":"מֶלֶךְ עוֹזֵר וּמוֹשִׁיעַ וּמָגֵן. בָּרוּךְ אַתָּה יהוה, מָגֵן אַבְרָהָם.","cond":["musaf"]},{"kind":"text","text":"אַתָּה גִּבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֵּה מֵתִים אַתָּה רַב לְהוֹשִׁיעַ,","cond":["musaf"]},{"kind":"summer","text":"מוֹרִיד הַטָּל,","cond":["musaf","summerTal"]},{"kind":"winter","text":"מַשִּׁיב הָרוּחַ וּמוֹרִיד הַגֶּשֶׁם,","cond":["musaf","winterTal"]},{"kind":"text","text":"מְכַלְכֵּל חַיִּים בְּחֶסֶד, מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים, סוֹמֵךְ נוֹפְלִים, וְרוֹפֵא חוֹלִים וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמוּנָתוֹ לִישֵׁנֵי עָפָר. מִי כָמוֹךָ בַּעַל גְּבוּרוֹת וּמִי דּוֹמֶה לָךְ, מֶלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִיחַ יְשׁוּעָה.","cond":["musaf"]},{"kind":"special","text":"מִי כָמוֹךָ אַב הָרַחֲמָן, זוֹכֵר יְצוּרָיו לְחַיִּים בְּרַחֲמִים.","cond":["musaf","ayt"]},{"kind":"text","text":"וְנֶאֱמָן אַתָּה לְהַחֲיוֹת מֵתִים. בָּרוּךְ אַתָּה יהוה, מְחַיֵּה הַמֵּתִים.","cond":["musaf"]},{"kind":"text","text":"אַתָּה קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ וּקְדוֹשִׁים בְּכָל יוֹם יְהַלְלוּךָ סֶּלָה, כִּי אֵל מֶלֶךְ גָּדוֹל וְקָדוֹשׁ אָתָּה.","cond":["musaf"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הָאֵל הַקָּדוֹשׁ.","cond":["musaf","noayt"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יהוה, הַמֶּלֶךְ הַקָּדוֹשׁ.","cond":["musaf","ayt"]},{"kind":"text","text":"רָאשֵׁי חֳדָשִׁים לְעַמְּךָ נָתָתָּ, זְמַן כַּפָּרָה לְכָל תּוֹלְדוֹתָם, בִּהְיוֹתָם מַקְרִיבִים לְפָנֶיךָ זִבְחֵי רָצוֹן, וּשְׂעִירֵי חַטָּאת לְכַפֵּר בַּעֲדָם, זִכָּרוֹן לְכֻלָּם יִהְיוּ, וּתְשׁוּעַת נַפְשָׁם מִיַּד שׂוֹנֵא. מִזְבֵּחַ חָדָשׁ בְּצִיּוֹן תָּכִין, וְעוֹלַת רֹאשׁ חֹדֶשׁ נַעֲלֶה עָלָיו, וּשְׂעִירֵי עִזִּים נַעֲשֶׂה בְרָצוֹן, וּבַעֲבוֹדַת בֵּית הַמִּקְדָּשׁ נִשְׂמַח כֻּלָּנוּ, וּבְשִׁירֵי דָּוִד עַבְדְּךָ הַנִּשְׁמָעִים בְּעִירֶךָ, הָאֲמוּרִים לִפְנֵי מִזְבְּחֶךָ, אַהֲבַת עוֹלָם תָּבִיא לָהֶם וּבְרִית אָבוֹת לַבָּנִים תִּזְכּוֹר. וַהֲבִיאֵנוּ לְצִיּוֹן עִירְךָ בְּרִנָּה, וְלִירוּשָׁלַיִם בֵּית מִקְדָּשְׁךָ בְּשִׂמְחַת עוֹלָם, וְשָׁם נַעֲשֶׂה לְפָנֶיךָ אֶת קָרְבְּנוֹת חוֹבוֹתֵינוּ, תְּמִידִים כְּסִדְרָם וּמוּסָפִים כְּהִלְכָתָם, וְאֶת מוּסַף יוֹם רֹאשׁ הַחֹדֶשׁ הַזֶּה נַעֲשֶׂה וְנַקְרִיב לְפָנֶיךָ בְּאַהֲבָה כְּמִצְוַת רְצוֹנֶךָ, כְּמוֹ שֶׁכָּתַבְתָּ עָלֵינוּ בְּתוֹרָתֶךָ עַל יְדֵי מֹשֶׁה עַבְדֶּךָ מִפִּי כְבוֹדֶךָ, כָּאָמוּר: וּבְרָאשֵׁי חָדְשֵׁיכֶם תַּקְרִיבוּ עוֹלָה לַיהוה, פָּרִים בְּנֵי בָקָר שְׁנַיִם וְאַיִל אֶחָד, כְּבָשִׂים בְּנֵי שָׁנָה שִׁבְעָה, תְּמִימִם: וּמִנְחָתָם וְנִסְכֵּיהֶם כִּמְדֻבָּר: שְׁלשָׁה עֶשְׂרֹנִים לַפָּר, וּשְׁנֵי עֶשְׂרֹנִים לָאָיִל, וְעִשָּׂרוֹן לַכֶּבֶשׂ, וְיַיִן כְּנִסְכּוֹ, וְשָׂעִיר לְכַפֵּר, וּשְׁנֵי תְמִידִים כְּהִלְכָתָם.\n\nאֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, חַדֵּשׁ עָלֵינוּ אֶת הַחֹדֶשׁ הַזֶּה לְטוֹבָה וְלִבְרָכָה, לְשָׂשׂוֹן וּלְשִׂמְחָה, לִישׁוּעָה וּלְנֶחָמָה, לְפַרְנָסָה וּלְכַלְכָּלָה, לְחַיִּים וּלְשָׁלוֹם, לִמְחִילַת חֵטְא וְלִסְלִיחַת עָווֹן.","cond":["musaf","rh"]},{"kind":"text","text":"וּלְכַפָּרַת פָּשַׁע.","cond":["musaf","rh","kaparatPasha"]},{"kind":"text","text":"וִיהִי הַחֹדֶשׁ הַזֶה סוֹף וְקֵץ לְכָל צָרוֹתֵינוּ, תְּחִלָּה וָרֹאשׁ לְפִדְיוֹן נַפְשֵׁנוּ, כִּי בְעַמְּךָ יִשְׂרָאֵל בָּחַרְתָּ מִכָּל הָאֻמּוֹת, וְחֻקֵּי רָאשֵׁי חֳדָשִׁים לָהֶם קָבָעְתָּ. בָּרוּךְ אַתָּה יהוה, מְקַדֵּשׁ יִשְׂרָאֵל וְרָאשֵׁי חֳדָשִׁים.","cond":["musaf","rh"]},{"kind":"text","text":"אַתָּה בְחַרְתָּנוּ מִכָּל הָעַמִּים, אָהַבְתָּ אוֹתָנוּ וְרָצִיתָ בָּנוּ, וְרוֹמַמְתָּנוּ מִכָּל הַלְּשׁוֹנוֹת וְקִדַּשְׁתָּנוּ בְּמִצְוׂתֶיךָ, וְקֵרַבְתָּנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶךָ, וְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ עָלֵינוּ קָרָאתָ. וַתִּתֶּן לָנוּ יהוה אֱלֹהֵינוּ בְּאַהֲבָה מוֹעֲדִים לְשִׂמְחָה, חַגִּים וּזְמַנִּים לְשָׂשׂוֹן אֶת יוֹם","cond":["musaf","pesach"]},{"kind":"text","text":"חַג הַמַּצּוֹת הַזֶּה, זְמַן חֵרוּתֵנוּ","cond":["musaf","pesach","pesach"]},{"kind":"text","text":"חַג הַסֻּכּוֹת הַזֶּה, זְמַן שִׂמְחָתֵנוּ","cond":["musaf","pesach","sucot"]},{"kind":"text","text":"מִקְרָא קֹדֶשׁ, זֵכֶר לִיצִיאַת מִצְרָיִם.\n\nוּמִפְּנֵי חֲטָאֵינוּ גָּלִינוּ מֵאַרְצֵנוּ, וְנִתְרַחַקְנוּ מֵעַל אַדְמָתֵנוּ, וְאֵין אֲנַחְנוּ יְכוֹלִים לַעֲלוֹת וְלֵרָאוֹת וּלְהִשְׁתַּחֲווֹת לְפָנֶיךָ, וְלַעֲשׂוֹת חוֹבוֹתֵינוּ בְּבֵית בְּחִירָתֶךָ, בַּבַּיִת הַגָּדוֹל וְהַקָּדוֹשׁ שֶׁנִּקְרָא שִׁמְךָ עָלָיו, מִפְּנֵי הַיָּד שֶׁנִּשְׁתַּלְּחָה בְּמִקְדָּשֶׁךָ. יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן, שֶׁתָּשׁוּב וּתְרַחֵם עָלֵינוּ וְעַל מִקְדָּשְׁךָ בְּרַחֲמֶיךָ הָרַבִּים, וְתִבְנֵהוּ מְהֵרָה וּתְגַדֵּל כְּבוֹדוֹ. אָבִינוּ מַלְכֵּנוּ, גַּלֵּה כְּבוֹד מַלְכוּתְךָ עָלֵינוּ מְהֵרָה, וְהוֹפַע וְהִנָּשֵׂא עָלֵינוּ לְעֵינֵי כָּל חָי, וְקָרֵב פְּזוּרֵינוּ מִבֵּין הַגּוֹיִם, וּנְפוּצוֹתֵינוּ כַּנֵּס מִיַּרְכְּתֵי אָרֶץ. וַהֲבִיאֵנוּ לְצִיּוֹן עִירְךָ בְּרִנָּה, וְלִירוּשָׁלַיִם בֵּית מִקְדָּשְׁךָ בְּשִׂמְחַת עוֹלָם, וְשָׁם נַעֲשֶׂה לְפָנֶיךָ אֶת קָרְבְּנוֹת חוֹבוֹתֵינוּ תְּמִידִים כְּסִדְרָם וּמוּסָפִים כְּהִלְכָתָם, וְאֶת מוּסַף יוֹם","cond":["musaf","pesach"]},{"kind":"text","text":"חַג הַמַּצּוֹת הַזֶּה","cond":["musaf","pesach","pesach"]},{"kind":"text","text":"חַג הַסֻּכּוֹת הַזֶּה","cond":["musaf","pesach","sucot"]},{"kind":"text","text":"נַעֲשֶׂה וְנַקְרִיב לְפָנֶיךָ בְּאַהֲבָה כְּמִצְוַת רְצוֹנֶךָ, כְּמוֹ שֶׁכָּתַבְתָּ עָלֵינוּ בְּתוֹרָתֶךָ עַל יְדֵי מֹשֶׁה עַבְדֶּךָ מִפִּי כְבוֹדֶךָ, כָּאָמוּר:","cond":["musaf","pesach"]},{"kind":"text","text":"וְהִקְרַבְתֶּם אִשֶּׁה עֹלָה לַיהוה, פָּרִים בְּנֵי בָקָר שְׁנַיִם, וְאַיִל אֶחָד, וְשִׁבְעָה כְבָשִׂים בְּנֵי שָׁנָה, תְּמִימִם יִהְיוּ לָכֶם:\nוּמִנְחָתָם וְנִסְכֵּיהֶם כִּמְדֻבָּר: שְׁלֹשָׁה עֶשְׂרֹנִים לַפָּר, וּשְׁנֵי עֶשְׂרֹנִים לָאָיִל, וְעִשָּׂרוֹן לַכֶּבֶשׂ, וְיַיִן כְּנִסְכּוֹ, וְשָׂעִיר לְכַפֵּר, וּשְׁנֵי תְמִידִים כְּהִלְכָתָם.","cond":["musaf","pesach","pesach"]},{"kind":"text","text":":-:-","cond":["musaf","pesach","sucot"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן רַחֵם עָלֵינוּ, טוֹב וּמֵטִיב הִדָּרֶשׁ לָנוּ, שׁוּבָה אֵלֵינוּ בַּהֲמוֹן רַחֲמֶיךָ, בִּגְלַל אָבוֹת שֶׁעָשׂוּ רְצוֹנֶךָ. בְּנֵה בֵיתְךָ כְּבַתְּחִלָּה, וְכוֹנֵן מִקְדָּשְׁךָ עַל מְכוֹנוֹ, וְהַרְאֵנוּ בְּבִנְיָנוֹ וְשַׂמְּחֵנוּ בְּתִקּוּנוֹ, וְהָשֵׁב כֹּהֲנִים לַעֲבוֹדָתָם וּלְוִיִּם לְשִׁירָם וּלְזִמְרָם, וְהָשֵׁב יִשְׂרָאֵל לִנְוֵיהֶם. וְשָׁם נַעֲלֶה וְנֵרָאֶה וְנִשְׁתַּחֲוֶה לְפָנֶיךָ בְּשָׁלֹשׁ פַּעֲמֵי רְגָלֵינוּ כַּכָּתוּב בְּתוֹרָתֶךָ: שָׁלֹשׁ פְּעָמִים בַּשָּׁנָה יֵרָאֶה כָל זְכוּרְךָ אֶת פְּנֵי יהוה אֱלֹהֶיךָ בַּמָּקום אֲשֶׁר יִבְחָר, בְּחַג הַמַּצּוֹת, וּבְחַג הַשָּׁבֻעוֹת, וּבְחַג הַסֻּכּוֹת, וְלא יֵרָאֶה אֶת פְּנֵי יהוה רֵיקָם: אִישׁ כְּמַתְּנַת יָדוֹ, כְּבִרְכַּת יהוה אֱלֹהֶיךָ אֲשֶׁר נָתַן לָךְ:\n\nוְהַשִּׂיאֵנוּ יהוה אֱלֹהֵינוּ אֶת בִּרְכַּת מוֹעֲדֶיךָ, לְחַיִּים וּלְשָׁלוֹם, לְשִׂמְחָה וּלְשָׂשׂוֹן, כַּאֲשֶׁר רָצִיתָ וְאָמַרְתָּ לְבָרְכֵנוּ. קַדְּשֵׁנוּ בְּמִצְוׂתֶיךָ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתֶךָ, שַׂבְּעֵנוּ מִטּוּבֶךָ, וְשַׂמְּחֵנוּ בִּישׁוּעָתֶךָ, וְטַהֵר לִבֵּנוּ לְעָבְדְּךָ בֶּאֱמֶת, וְהַנְחִילֵנוּ יהוה אֱלֹהֵינוּ בְּשִׂמְחָה וּבְשָׂשׂוֹן מוֹעֲדֵי קָדְשֶׁךָ, וְיִשְׂמְחוּ בְךָ יִשְׂרָאֵל מְקַדְּשֵׁי שְׁמֶךָ. בָּרוּךְ אַתָּה יהוה, מְקַדֵּשׁ יִשְׂרָאֵל וְהַזְּמַנִּים.","cond":["musaf","pesach"]},{"kind":"text","text":"אַתָּה בְחַרְתָּנוּ מִכָּל הָעַמִּים, אָהַבְתָּ אוֹתָנוּ וְרָצִיתָ בָּנוּ, וְרוֹמַמְתָּנוּ מִכָּל הַלְּשׁוֹנוֹת וְקִדַּשְׁתָּנוּ בְּמִצְוׂתֶיךָ, וְקֵרַבְתָּנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶךָ, וְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ עָלֵינוּ קָרָאתָ. וַתִּתֶּן לָנוּ יהוה אֱלֹהֵינוּ בְּאַהֲבָה מוֹעֲדִים לְשִׂמְחָה, חַגִּים וּזְמַנִּים לְשָׂשׂוֹן אֶת יוֹם","cond":["musaf","sucot"]},{"kind":"text","text":"חַג הַמַּצּוֹת הַזֶּה, זְמַן חֵרוּתֵנוּ","cond":["musaf","sucot","pesach"]},{"kind":"text","text":"חַג הַסֻּכּוֹת הַזֶּה, זְמַן שִׂמְחָתֵנוּ","cond":["musaf","sucot","sucot"]},{"kind":"text","text":"מִקְרָא קֹדֶשׁ, זֵכֶר לִיצִיאַת מִצְרָיִם.\n\nוּמִפְּנֵי חֲטָאֵינוּ גָּלִינוּ מֵאַרְצֵנוּ, וְנִתְרַחַקְנוּ מֵעַל אַדְמָתֵנוּ, וְאֵין אֲנַחְנוּ יְכוֹלִים לַעֲלוֹת וְלֵרָאוֹת וּלְהִשְׁתַּחֲווֹת לְפָנֶיךָ, וְלַעֲשׂוֹת חוֹבוֹתֵינוּ בְּבֵית בְּחִירָתֶךָ, בַּבַּיִת הַגָּדוֹל וְהַקָּדוֹשׁ שֶׁנִּקְרָא שִׁמְךָ עָלָיו, מִפְּנֵי הַיָּד שֶׁנִּשְׁתַּלְּחָה בְּמִקְדָּשֶׁךָ. יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן, שֶׁתָּשׁוּב וּתְרַחֵם עָלֵינוּ וְעַל מִקְדָּשְׁךָ בְּרַחֲמֶיךָ הָרַבִּים, וְתִבְנֵהוּ מְהֵרָה וּתְגַדֵּל כְּבוֹדוֹ. אָבִינוּ מַלְכֵּנוּ, גַּלֵּה כְּבוֹד מַלְכוּתְךָ עָלֵינוּ מְהֵרָה, וְהוֹפַע וְהִנָּשֵׂא עָלֵינוּ לְעֵינֵי כָּל חָי, וְקָרֵב פְּזוּרֵינוּ מִבֵּין הַגּוֹיִם, וּנְפוּצוֹתֵינוּ כַּנֵּס מִיַּרְכְּתֵי אָרֶץ. וַהֲבִיאֵנוּ לְצִיּוֹן עִירְךָ בְּרִנָּה, וְלִירוּשָׁלַיִם בֵּית מִקְדָּשְׁךָ בְּשִׂמְחַת עוֹלָם, וְשָׁם נַעֲשֶׂה לְפָנֶיךָ אֶת קָרְבְּנוֹת חוֹבוֹתֵינוּ תְּמִידִים כְּסִדְרָם וּמוּסָפִים כְּהִלְכָתָם, וְאֶת מוּסַף יוֹם","cond":["musaf","sucot"]},{"kind":"text","text":"חַג הַמַּצּוֹת הַזֶּה","cond":["musaf","sucot","pesach"]},{"kind":"text","text":"חַג הַסֻּכּוֹת הַזֶּה","cond":["musaf","sucot","sucot"]},{"kind":"text","text":"נַעֲשֶׂה וְנַקְרִיב לְפָנֶיךָ בְּאַהֲבָה כְּמִצְוַת רְצוֹנֶךָ, כְּמוֹ שֶׁכָּתַבְתָּ עָלֵינוּ בְּתוֹרָתֶךָ עַל יְדֵי מֹשֶׁה עַבְדֶּךָ מִפִּי כְבוֹדֶךָ, כָּאָמוּר:","cond":["musaf","sucot"]},{"kind":"text","text":"וְהִקְרַבְתֶּם אִשֶּׁה עֹלָה לַיהוה, פָּרִים בְּנֵי בָקָר שְׁנַיִם, וְאַיִל אֶחָד, וְשִׁבְעָה כְבָשִׂים בְּנֵי שָׁנָה, תְּמִימִם יִהְיוּ לָכֶם:\nוּמִנְחָתָם וְנִסְכֵּיהֶם כִּמְדֻבָּר: שְׁלֹשָׁה עֶשְׂרֹנִים לַפָּר, וּשְׁנֵי עֶשְׂרֹנִים לָאָיִל, וְעִשָּׂרוֹן לַכֶּבֶשׂ, וְיַיִן כְּנִסְכּוֹ, וְשָׂעִיר לְכַפֵּר, וּשְׁנֵי תְמִידִים כְּהִלְכָתָם.","cond":["musaf","sucot","pesach"]},{"kind":"text","text":":-:-","cond":["musaf","sucot","sucot"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן רַחֵם עָלֵינוּ, טוֹב וּמֵטִיב הִדָּרֶשׁ לָנוּ, שׁוּבָה אֵלֵינוּ בַּהֲמוֹן רַחֲמֶיךָ, בִּגְלַל אָבוֹת שֶׁעָשׂוּ רְצוֹנֶךָ. בְּנֵה בֵיתְךָ כְּבַתְּחִלָּה, וְכוֹנֵן מִקְדָּשְׁךָ עַל מְכוֹנוֹ, וְהַרְאֵנוּ בְּבִנְיָנוֹ וְשַׂמְּחֵנוּ בְּתִקּוּנוֹ, וְהָשֵׁב כֹּהֲנִים לַעֲבוֹדָתָם וּלְוִיִּם לְשִׁירָם וּלְזִמְרָם, וְהָשֵׁב יִשְׂרָאֵל לִנְוֵיהֶם. וְשָׁם נַעֲלֶה וְנֵרָאֶה וְנִשְׁתַּחֲוֶה לְפָנֶיךָ בְּשָׁלֹשׁ פַּעֲמֵי רְגָלֵינוּ כַּכָּתוּב בְּתוֹרָתֶךָ: שָׁלֹשׁ פְּעָמִים בַּשָּׁנָה יֵרָאֶה כָל זְכוּרְךָ אֶת פְּנֵי יהוה אֱלֹהֶיךָ בַּמָּקום אֲשֶׁר יִבְחָר, בְּחַג הַמַּצּוֹת, וּבְחַג הַשָּׁבֻעוֹת, וּבְחַג הַסֻּכּוֹת, וְלא יֵרָאֶה אֶת פְּנֵי יהוה רֵיקָם: אִישׁ כְּמַתְּנַת יָדוֹ, כְּבִרְכַּת יהוה אֱלֹהֶיךָ אֲשֶׁר נָתַן לָךְ:\n\nוְהַשִּׂיאֵנוּ יהוה אֱלֹהֵינוּ אֶת בִּרְכַּת מוֹעֲדֶיךָ, לְחַיִּים וּלְשָׁלוֹם, לְשִׂמְחָה וּלְשָׂשׂוֹן, כַּאֲשֶׁר רָצִיתָ וְאָמַרְתָּ לְבָרְכֵנוּ. קַדְּשֵׁנוּ בְּמִצְוׂתֶיךָ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתֶךָ, שַׂבְּעֵנוּ מִטּוּבֶךָ, וְשַׂמְּחֵנוּ בִּישׁוּעָתֶךָ, וְטַהֵר לִבֵּנוּ לְעָבְדְּךָ בֶּאֱמֶת, וְהַנְחִילֵנוּ יהוה אֱלֹהֵינוּ בְּשִׂמְחָה וּבְשָׂשׂוֹן מוֹעֲדֵי קָדְשֶׁךָ, וְיִשְׂמְחוּ בְךָ יִשְׂרָאֵל מְקַדְּשֵׁי שְׁמֶךָ. בָּרוּךְ אַתָּה יהוה, מְקַדֵּשׁ יִשְׂרָאֵל וְהַזְּמַנִּים.","cond":["musaf","sucot"]},{"kind":"text","text":"רְצֵה יהוה אֱלֹהֵינוּ בְּעַמְּךָ יִשְׂרָאֵל וְלִתְפִלָּתָם שְׁעֵה, וְהָשֵׁב אֶת הָעֲבוֹדָה לִדְבִיר בֵּיתֶךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם, מְהֵרָה בְּאַהֲבָה תְקַבֵּל בְּרָצוֹן. וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּךָ. וְתֶחֱזֶינָה עֵינֵינוּ בְּשׁוּבְךָ לְצִיּוֹן בְּרַחֲמִים. בָּרוּךְ אַתָּה יהוה, הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן.","cond":["musaf"]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שָׁאַתָּה הוּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ לְעוֹלָם וָעֵד. צוּר חַיֵּינוּ, מָגֵן יִשְׁעֵנוּ אַתָּה הוּא לְדוֹר וָדוֹר. נוֹדֶה לְּךָ וּנְסַפֵּר תְּהִלָּתֶךָ עַל חַיֵּינוּ הַמְּסוּרִים בְּיָדֶךָ, וְעַל נִשְׁמוֹתֵינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּיךָ שֶׁבְּכָל יוֹם עִמָּנוּ, וְעַל נִפְלְאוֹתֶיךָ וְטוֹבוֹתֶיךָ שֶׁבְּכָל עֵת, עֶרֶב וָבֹקֶר וְצָהֳרָיִם. הַטּוֹב כִּי לֹא כָלוּ רַחֲמֶיךָ, וְהַמְרַחֵם כִּי לֹא תַמּוּ חֲסָדֶיךָ, כִּי מֵעוֹלָם קִוִּינוּ לָךְ.","cond":["musaf"]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מַתִּתְיָהוּ בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְהַשְׁכִּיחָם תּוֹרָתֶךָ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנֶךָ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּטְמֵאִים בְּיַד טְהוֹרִים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, וּלְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמֶךָ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כֵּן בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ לְהוֹדוֹת וּלְהַלֵּל לְשִׁמְךָ הַגָּדוֹל. (נ\"א: וְקָבְעוּ שְׁמוֹנַת יָמִים אֵלּוּ בְּהַלֵּל וּבְהוֹדָאָה וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה.)","cond":["musaf","chanuka"]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים, מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ, וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ, וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְּרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ (, וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה).","cond":["musaf","purim"]},{"kind":"text","text":"וְעַל כֻּלָּם יִתְבָּרַךְ וְיִתְרוֹמַם וְיִתְנַשֵּׂא שִׁמְךָ מַלְכֵּנוּ תָּמִיד לְעוֹלָם וָעֶד.","cond":["musaf"]},{"kind":"special","text":"וּכְתֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶךָ.","cond":["musaf","ayt"]},{"kind":"text","text":"וְכֹל הַחַיִּים יוֹדוּךָ סֶלָה, וִיהַלְלוּ וִיבָרְכוּ אֶת שִׁמְךָ הַגָּדוֹל בֶּאֱמֶת לְעוֹלָם כִּי טוֹב, הָאֵל יְשׁוּעָתֵנוּ וְעֶזְרָתֵנוּ סֶלָה, הָאֵל הַטּוֹב. בָּרוּך אַתָּה יהוה, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת.","cond":["musaf"]},{"kind":"text","text":"שִׂים שָׁלוֹם טוֹבָה וּבְרָכָה, חַיִּים חֵן וָחֶסֶד וְרַחֲמִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל עַמֶּךָ. בָּרְכֵנוּ אָבִינוּ כֻּלָּנוּ כְּאֶחָד (יַחַד) בְּאוֹר פָּנֶיךָ, כִּי בְאוֹר פָּנֶיךָ נָתַתָּ לָּנוּ יהוה אֱלֹהֵינוּ תּוֹרַת חַיִּים וְאַהֲבַת חֶסֶד, וּצְדָקָה וּבְרָכָה וְרַחֲמִים וְחַיִּים וְשָׁלוֹם. וְטוֹב יִהְיֶה בְעֵינֶיךָ לְבָרְכֵנוּ וּלְבָרֵךְ אֶת כָּל עַמְּךָ יִשְׂרָאֵל בְּכָל עֵת וּבְכָל שָׁעָה בִּשְׁלוֹמֶךָ (בְּרֹב עֹז וְשָׁלוֹם).","cond":["musaf"]},{"kind":"special","text":"בְּסֵפֶר חַיִּים, בְּרָכָה וְשָׁלוֹם, וּפַרְנָסָה טוֹבָה, וּגְזֵרוֹת טוֹבוֹת, יְשׁוּעוֹת וְנֶחָמוֹת, נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ, אֲנַחְנוּ וְכָל עַמְּךָ בֵּית יִשְׂרָאֵל, לְחַיִּים טוֹבִים וּלְשָׁלוֹם.","cond":["musaf","ayt"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הַמְבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם.","cond":["musaf"]},{"kind":"text","text":"יִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ. יהוה צוּרִי וְגוֹאֲלִי:\nאֱלֹהַי, נְצֹר לְשׁוֹנִי מֵרָע וּשְׂפָתַי מִדַּבֵּר מִרְמָה, וְלִמְקַלְלַי נַפְשִׁי תִדֹּם, וְנַפְשִׁי כֶּעָפָר לַכֹּל תִּהְיֶה. פְּתַח לִבִּי בְּתוֹרָתֶךָ, וְאַחֲרֵי מִצְוׂתֶיךָ תִּרְדֹף נַפְשִׁי. וְכָל הַקָּמִים וְהַחוֹשְׁבִים עָלַי לְרָעָה, מְהֵרָה הָפֵר עֲצָתָם וְקַלְקֵל מַחֲשַׁבְתָּם.\n(יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁלֹּא תַעֲלֶה קִנְאַת אָדָם עָלַי וְלֹא קִנְאָתִי עַל אֲחֵרִים, וְשֶׁלֹּא אֶכְעוֹס הַיּוֹם וְשֶׁלֹּא אַכְעִיסֶךָ. וְתַצִּילֵנִי מִיֵּצֶר הָרָע, וְתֵן בְּלִבִּי הַכְנָעָה וַעֲנָוָה. מַלְכֵּנוּ וֵאלֹהֵינוּ אֱלוֹהַּ כָּל בָּשָׂר, יַחֵד שִׁמְךָ בְּעוֹלָמֶךָ, בְּנֵה עִירֶךָ, יַסֵּד בֵּיתֶךָ וְשַׁכְלֵל הֵיכָלֶךָ, וְקַבֵּץ קִבּוּץ גָלֻיּוֹת וּפְדֵה צֹאנֶךָ וְשַׂמַּח עָדָתֶךָ.)\nעֲשֵׂה לְמַעַן שְׁמֶךָ, עֲשֵׂה לְמַעַן יְמִינֶךָ, עֲשֵׂה לְמַעַן תּוֹרָתֶךָ, עֲשֵׂה לְמַעַן קְדֻשָּׁתֶךָ. לְמַעַן יֵחָלְצוּן יְדִידֶיךָ הוֹשִׁיעָה יְמִינְךָ וַעֲנֵנִי:\nיִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:","cond":["musaf"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["musaf","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["musaf","ayt"]},{"kind":"text","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁיִּבָּנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵינוּ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתֶךָ, וְשָׁם נַעֲבָדְךָ בְּיִרְאָה כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמוֹנִיּוֹת. וְעָרְבָה לַיהוה מִנְחַת יְהוּדָה וִירוּשָׁלָיִם כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמֹנִיּוֹת:","cond":["musaf"]},{"kind":"header","text":"חזרת הש\"ץ","cond":["musaf"]},{"kind":"instruction","text":"חזרת הש\"ץ","cond":["musaf"]},{"kind":"text","text":"כִּי שֵׁם יהוה אֶקְרָא, הָבוּ גֹדֶל לֵאלֹהֵינוּ:\nאֲדֹנָי, שְׂפָתַי תִּפְתָּח, וּפִי יַגִּיד תְּהִלָּתֶךָ:","cond":["musaf"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק, וֵאלֹהֵי יַעֲקֹב, הָאֵל הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, וְקוֹנֵה הַכֹּל, וְזוֹכֵר חַסְדֵי אָבוֹת, וּמֵבִיא גוֹאֵל לִבְנֵי בְנֵיהֶם לְמַעַן שְׁמוֹ בְּאַהֲבָה.","cond":["musaf"]},{"kind":"special","text":"זָכְרֵנוּ לְחַיִּים, מֶלֶךְ חָפֵץ בַּחַיִּים, וְכָתְבֵנוּ בְּסֵפֶר הַחַיִּים, לְמַעַנְךָ אֱלֹהִים חַיִּים.","cond":["musaf","ayt"]},{"kind":"text","text":"מֶלֶךְ עוֹזֵר וּמוֹשִׁיעַ וּמָגֵן. בָּרוּךְ אַתָּה יהוה, מָגֵן אַבְרָהָם.","cond":["musaf"]},{"kind":"text","text":"אַתָּה גִּבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֵּה מֵתִים אַתָּה רַב לְהוֹשִׁיעַ,","cond":["musaf"]},{"kind":"summer","text":"מוֹרִיד הַטָּל,","cond":["musaf","summerTal"]},{"kind":"winter","text":"מַשִּׁיב הָרוּחַ וּמוֹרִיד הַגֶּשֶׁם,","cond":["musaf","winterTal"]},{"kind":"text","text":"מְכַלְכֵּל חַיִּים בְּחֶסֶד, מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים, סוֹמֵךְ נוֹפְלִים, וְרוֹפֵא חוֹלִים וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמוּנָתוֹ לִישֵׁנֵי עָפָר. מִי כָמוֹךָ בַּעַל גְּבוּרוֹת וּמִי דּוֹמֶה לָךְ, מֶלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִיחַ יְשׁוּעָה.","cond":["musaf"]},{"kind":"special","text":"מִי כָמוֹךָ אַב הָרַחֲמָן, זוֹכֵר יְצוּרָיו לְחַיִּים בְּרַחֲמִים.","cond":["musaf","ayt"]},{"kind":"text","text":"וְנֶאֱמָן אַתָּה לְהַחֲיוֹת מֵתִים. בָּרוּךְ אַתָּה יהוה, מְחַיֵּה הַמֵּתִים.","cond":["musaf"]},{"kind":"header","text":"קדושה","cond":["musaf"]},{"kind":"instruction","text":"קדושה בחזרת הש\"ץ:","cond":["musaf"]},{"kind":"text","text":"כֶּתֶר יִתְּנוּ לְךָ יהוה אֱלֹהֵינוּ מַלְאָכִים הֲמוֹנֵי מַעְלָה עִם עַמְּךָ יִשְׂרָאֵל קְבוּצֵי מַטָּה, יַחַד כֻּלָּם קְדֻשָּׁה לְךָ יְשַׁלֵּשׁוּ כַּדָּבָר הָאָמוּר עַל יַד נְבִיאֶךָ: וְקָרָא זֶה אֶל זֶה וְאָמַר:","cond":["musaf"]},{"kind":"text","text":"קו\"ח: קָדוֹשׁ, קָדוֹשׁ, קָדוֹשׁ יהוה צְבָאוֹת, מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ:\nחזן: לְעֻמָּתָם מְשַׁבְּחִים וְאוֹמְרִים:\nקו\"ח: בָּרוּךְ כְּבוֹד יהוה מִמְּקוֹמוֹ:\nחזן: וּבְדִבְרֵי קָדְשְׁךָ כָּתוּב לֵאמֹר:\nקו\"ח: יִמְלֹך יהוה לְעוֹלָם, אֱלֹהַיִך צִיּוֹן לְדֹר וָדֹר, הַלְלוּיָהּ:","cond":["musaf","noHoshanaRaba"]},{"kind":"text","text":"אַתָּה קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ וּקְדוֹשִׁים בְּכָל יוֹם יְהַלְלוּךָ סֶּלָה, כִּי אֵל מֶלֶךְ גָּדוֹל וְקָדוֹשׁ אָתָּה.","cond":["musaf","noHoshanaRaba"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הָאֵל הַקָּדוֹשׁ.","cond":["musaf","noHoshanaRaba","noayt"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יהוה, הַמֶּלֶךְ הַקָּדוֹשׁ.","cond":["musaf","noHoshanaRaba","ayt"]},{"kind":"text","text":"קו\"ח: קָדוֹשׁ, קָדוֹשׁ, קָדוֹשׁ יהוה צְבָאוֹת, מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ:\nחזן: כְּבוֹדוֹ מָלֵא עוֹלָם, מְשָׁרְתָיו שׁוֹאֲלִים זֶה לָזֶה אַיֵּה מְקוֹם כְּבוֹדוֹ לְהַעֲרִיצוֹ. לְעֻמָּתָם מְשַׁבְּחִים וְאוֹמְרִים:\nקו\"ח: בָּרוּךְ כְּבוֹד יהוה מִמְּקוֹמוֹ:\nחזן: מִמְּקוֹמוֹ הוּא יִפֶן בְּרַחֲמָיו לְעַמּוֹ, וְיָחֹן עַם הַמְיַחֲדִים שְׁמוֹ עֶרֶב וָבֹקֶר בְּכָל יוֹם תָּמִיד, פַּעֲמַיִם בְּאַהֲבָה שְׁמַע אוֹמְרִים:\nקו\"ח: שְׁמַע יִשרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:\nחזן: הוּא אֱלֹהֵינוּ, הוּא אָבִינוּ, הוּא מַלְכֵּנוּ, הוּא מוֹשִׁיעֵנוּ, וְהוּא יוֹשִׁיעֵנוּ וְיִגְאָלֵנוּ שֵׁנִית וְיַשְׁמִיעֵנוּ בְּרַחֲמָיו לְעֵינֵי כָּל חַי לֵאמֹר: הֵן גָּאַלְתִּי אֶתְכֶם אַחֲרִית כְּרֵאשִׁית לִהְיוֹת לָכֶם לֵאלֹהִים,\nקו\"ח: אֲנִי יהוה אֱלֹהֵיכֶם:\nקו\"ח: אַדִּיר אַדִּירֵנוּ, יהוה אֲדֹנֵינוּ, מָה אַדִּיר שִׁמְךָ בְּכָל הָאָרֶץ: וְהָיָה יהוה לְמֶלֶךְ עַל כָּל הָאָרֶץ, בַּיּוֹם הַהוּא יִהְיֶה יהוה אֶחָד וּשְמוֹ אֶחָד:\nחזן: וּבְדִבְרֵי קָדְשְׁךָ כָּתוּב לֵאמֹר:\nקו\"ח: יִמְלֹך יהוה לְעוֹלָם, אֱלֹהַיִך צִיּוֹן לְדֹר וָדֹר, הַלְלוּיָהּ:\n\nלְדוֹר וָדוֹר נָגִיד גָדְלֶךָ וּלְנֵצַח נְצָחִים קְדֻשָּׁתְךָ נַקְדִּישׁ, וְשִׁבְחֲךָ אֱלֹהֵינוּ מִפִּינוּ לֹא יָמוּשׁ לְעוֹלָם וָעֵד, כִּי אֵל מֶלֶךְ גָּדוֹל וְקָדוֹשׁ אָתָּה. בָּרוּךְ אַתָּה יהוה, הָאֵל הַקָּדוֹשׁ.","cond":["musaf","HoshanaRaba"]},{"kind":"text","text":"רָאשֵׁי חֳדָשִׁים לְעַמְּךָ נָתָתָּ, זְמַן כַּפָּרָה לְכָל תּוֹלְדוֹתָם, בִּהְיוֹתָם מַקְרִיבִים לְפָנֶיךָ זִבְחֵי רָצוֹן, וּשְׂעִירֵי חַטָּאת לְכַפֵּר בַּעֲדָם, זִכָּרוֹן לְכֻלָּם יִהְיוּ, וּתְשׁוּעַת נַפְשָׁם מִיַּד שׂוֹנֵא. מִזְבֵּחַ חָדָשׁ בְּצִיּוֹן תָּכִין, וְעוֹלַת רֹאשׁ חֹדֶשׁ נַעֲלֶה עָלָיו, וּשְׂעִירֵי עִזִּים נַעֲשֶׂה בְרָצוֹן, וּבַעֲבוֹדַת בֵּית הַמִּקְדָּשׁ נִשְׂמַח כֻּלָּנוּ, וּבְשִׁירֵי דָּוִד עַבְדְּךָ הַנִּשְׁמָעִים בְּעִירֶךָ, הָאֲמוּרִים לִפְנֵי מִזְבְּחֶךָ, אַהֲבַת עוֹלָם תָּבִיא לָהֶם וּבְרִית אָבוֹת לַבָּנִים תִּזְכּוֹר. וַהֲבִיאֵנוּ לְצִיּוֹן עִירְךָ בְּרִנָּה, וְלִירוּשָׁלַיִם בֵּית מִקְדָּשְׁךָ בְּשִׂמְחַת עוֹלָם, וְשָׁם נַעֲשֶׂה לְפָנֶיךָ אֶת קָרְבְּנוֹת חוֹבוֹתֵינוּ, תְּמִידִים כְּסִדְרָם וּמוּסָפִים כְּהִלְכָתָם, וְאֶת מוּסַף יוֹם רֹאשׁ הַחֹדֶשׁ הַזֶּה נַעֲשֶׂה וְנַקְרִיב לְפָנֶיךָ בְּאַהֲבָה כְּמִצְוַת רְצוֹנֶךָ, כְּמוֹ שֶׁכָּתַבְתָּ עָלֵינוּ בְּתוֹרָתֶךָ עַל יְדֵי מֹשֶׁה עַבְדֶּךָ מִפִּי כְבוֹדֶךָ, כָּאָמוּר: וּבְרָאשֵׁי חָדְשֵׁיכֶם תַּקְרִיבוּ עוֹלָה לַיהוה, פָּרִים בְּנֵי בָקָר שְׁנַיִם וְאַיִל אֶחָד, כְּבָשִׂים בְּנֵי שָׁנָה שִׁבְעָה, תְּמִימִם: וּמִנְחָתָם וְנִסְכֵּיהֶם כִּמְדֻבָּר: שְׁלשָׁה עֶשְׂרֹנִים לַפָּר, וּשְׁנֵי עֶשְׂרֹנִים לָאָיִל, וְעִשָּׂרוֹן לַכֶּבֶשׂ, וְיַיִן כְּנִסְכּוֹ, וְשָׂעִיר לְכַפֵּר, וּשְׁנֵי תְמִידִים כְּהִלְכָתָם.\n\nאֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, חַדֵּשׁ עָלֵינוּ אֶת הַחֹדֶשׁ הַזֶּה לְטוֹבָה וְלִבְרָכָה, לְשָׂשׂוֹן וּלְשִׂמְחָה, לִישׁוּעָה וּלְנֶחָמָה, לְפַרְנָסָה וּלְכַלְכָּלָה, לְחַיִּים וּלְשָׁלוֹם, לִמְחִילַת חֵטְא וְלִסְלִיחַת עָווֹן.","cond":["musaf","rh"]},{"kind":"text","text":"וּלְכַפָּרַת פָּשַׁע.","cond":["musaf","rh","kaparatPasha"]},{"kind":"text","text":"וִיהִי הַחֹדֶשׁ הַזֶה סוֹף וְקֵץ לְכָל צָרוֹתֵינוּ, תְּחִלָּה וָרֹאשׁ לְפִדְיוֹן נַפְשֵׁנוּ, כִּי בְעַמְּךָ יִשְׂרָאֵל בָּחַרְתָּ מִכָּל הָאֻמּוֹת, וְחֻקֵּי רָאשֵׁי חֳדָשִׁים לָהֶם קָבָעְתָּ. בָּרוּךְ אַתָּה יהוה, מְקַדֵּשׁ יִשְׂרָאֵל וְרָאשֵׁי חֳדָשִׁים.","cond":["musaf","rh"]},{"kind":"text","text":"אַתָּה בְחַרְתָּנוּ מִכָּל הָעַמִּים, אָהַבְתָּ אוֹתָנוּ וְרָצִיתָ בָּנוּ, וְרוֹמַמְתָּנוּ מִכָּל הַלְּשׁוֹנוֹת וְקִדַּשְׁתָּנוּ בְּמִצְוׂתֶיךָ, וְקֵרַבְתָּנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶךָ, וְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ עָלֵינוּ קָרָאתָ. וַתִּתֶּן לָנוּ יהוה אֱלֹהֵינוּ בְּאַהֲבָה מוֹעֲדִים לְשִׂמְחָה, חַגִּים וּזְמַנִּים לְשָׂשׂוֹן אֶת יוֹם","cond":["musaf","pesach"]},{"kind":"text","text":"חַג הַמַּצּוֹת הַזֶּה, זְמַן חֵרוּתֵנוּ","cond":["musaf","pesach","pesach"]},{"kind":"text","text":"חַג הַסֻּכּוֹת הַזֶּה, זְמַן שִׂמְחָתֵנוּ","cond":["musaf","pesach","sucot"]},{"kind":"text","text":"מִקְרָא קֹדֶשׁ, זֵכֶר לִיצִיאַת מִצְרָיִם.\n\nוּמִפְּנֵי חֲטָאֵינוּ גָּלִינוּ מֵאַרְצֵנוּ, וְנִתְרַחַקְנוּ מֵעַל אַדְמָתֵנוּ, וְאֵין אֲנַחְנוּ יְכוֹלִים לַעֲלוֹת וְלֵרָאוֹת וּלְהִשְׁתַּחֲווֹת לְפָנֶיךָ, וְלַעֲשׂוֹת חוֹבוֹתֵינוּ בְּבֵית בְּחִירָתֶךָ, בַּבַּיִת הַגָּדוֹל וְהַקָּדוֹשׁ שֶׁנִּקְרָא שִׁמְךָ עָלָיו, מִפְּנֵי הַיָּד שֶׁנִּשְׁתַּלְּחָה בְּמִקְדָּשֶׁךָ. יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן, שֶׁתָּשׁוּב וּתְרַחֵם עָלֵינוּ וְעַל מִקְדָּשְׁךָ בְּרַחֲמֶיךָ הָרַבִּים, וְתִבְנֵהוּ מְהֵרָה וּתְגַדֵּל כְּבוֹדוֹ. אָבִינוּ מַלְכֵּנוּ, גַּלֵּה כְּבוֹד מַלְכוּתְךָ עָלֵינוּ מְהֵרָה, וְהוֹפַע וְהִנָּשֵׂא עָלֵינוּ לְעֵינֵי כָּל חָי, וְקָרֵב פְּזוּרֵינוּ מִבֵּין הַגּוֹיִם, וּנְפוּצוֹתֵינוּ כַּנֵּס מִיַּרְכְּתֵי אָרֶץ. וַהֲבִיאֵנוּ לְצִיּוֹן עִירְךָ בְּרִנָּה, וְלִירוּשָׁלַיִם בֵּית מִקְדָּשְׁךָ בְּשִׂמְחַת עוֹלָם, וְשָׁם נַעֲשֶׂה לְפָנֶיךָ אֶת קָרְבְּנוֹת חוֹבוֹתֵינוּ תְּמִידִים כְּסִדְרָם וּמוּסָפִים כְּהִלְכָתָם, וְאֶת מוּסַף יוֹם","cond":["musaf","pesach"]},{"kind":"text","text":"חַג הַמַּצּוֹת הַזֶּה","cond":["musaf","pesach","pesach"]},{"kind":"text","text":"חַג הַסֻּכּוֹת הַזֶּה","cond":["musaf","pesach","sucot"]},{"kind":"text","text":"נַעֲשֶׂה וְנַקְרִיב לְפָנֶיךָ בְּאַהֲבָה כְּמִצְוַת רְצוֹנֶךָ, כְּמוֹ שֶׁכָּתַבְתָּ עָלֵינוּ בְּתוֹרָתֶךָ עַל יְדֵי מֹשֶׁה עַבְדֶּךָ מִפִּי כְבוֹדֶךָ, כָּאָמוּר:","cond":["musaf","pesach"]},{"kind":"text","text":"וְהִקְרַבְתֶּם אִשֶּׁה עֹלָה לַיהוה, פָּרִים בְּנֵי בָקָר שְׁנַיִם, וְאַיִל אֶחָד, וְשִׁבְעָה כְבָשִׂים בְּנֵי שָׁנָה, תְּמִימִם יִהְיוּ לָכֶם:\nוּמִנְחָתָם וְנִסְכֵּיהֶם כִּמְדֻבָּר: שְׁלֹשָׁה עֶשְׂרֹנִים לַפָּר, וּשְׁנֵי עֶשְׂרֹנִים לָאָיִל, וְעִשָּׂרוֹן לַכֶּבֶשׂ, וְיַיִן כְּנִסְכּוֹ, וְשָׂעִיר לְכַפֵּר, וּשְׁנֵי תְמִידִים כְּהִלְכָתָם.","cond":["musaf","pesach","pesach"]},{"kind":"text","text":":-:-","cond":["musaf","pesach","sucot"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן רַחֵם עָלֵינוּ, טוֹב וּמֵטִיב הִדָּרֶשׁ לָנוּ, שׁוּבָה אֵלֵינוּ בַּהֲמוֹן רַחֲמֶיךָ, בִּגְלַל אָבוֹת שֶׁעָשׂוּ רְצוֹנֶךָ. בְּנֵה בֵיתְךָ כְּבַתְּחִלָּה, וְכוֹנֵן מִקְדָּשְׁךָ עַל מְכוֹנוֹ, וְהַרְאֵנוּ בְּבִנְיָנוֹ וְשַׂמְּחֵנוּ בְּתִקּוּנוֹ, וְהָשֵׁב כֹּהֲנִים לַעֲבוֹדָתָם וּלְוִיִּם לְשִׁירָם וּלְזִמְרָם, וְהָשֵׁב יִשְׂרָאֵל לִנְוֵיהֶם. וְשָׁם נַעֲלֶה וְנֵרָאֶה וְנִשְׁתַּחֲוֶה לְפָנֶיךָ בְּשָׁלֹשׁ פַּעֲמֵי רְגָלֵינוּ כַּכָּתוּב בְּתוֹרָתֶךָ: שָׁלֹשׁ פְּעָמִים בַּשָּׁנָה יֵרָאֶה כָל זְכוּרְךָ אֶת פְּנֵי יהוה אֱלֹהֶיךָ בַּמָּקום אֲשֶׁר יִבְחָר, בְּחַג הַמַּצּוֹת, וּבְחַג הַשָּׁבֻעוֹת, וּבְחַג הַסֻּכּוֹת, וְלא יֵרָאֶה אֶת פְּנֵי יהוה רֵיקָם: אִישׁ כְּמַתְּנַת יָדוֹ, כְּבִרְכַּת יהוה אֱלֹהֶיךָ אֲשֶׁר נָתַן לָךְ:\n\nוְהַשִּׂיאֵנוּ יהוה אֱלֹהֵינוּ אֶת בִּרְכַּת מוֹעֲדֶיךָ, לְחַיִּים וּלְשָׁלוֹם, לְשִׂמְחָה וּלְשָׂשׂוֹן, כַּאֲשֶׁר רָצִיתָ וְאָמַרְתָּ לְבָרְכֵנוּ. קַדְּשֵׁנוּ בְּמִצְוׂתֶיךָ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתֶךָ, שַׂבְּעֵנוּ מִטּוּבֶךָ, וְשַׂמְּחֵנוּ בִּישׁוּעָתֶךָ, וְטַהֵר לִבֵּנוּ לְעָבְדְּךָ בֶּאֱמֶת, וְהַנְחִילֵנוּ יהוה אֱלֹהֵינוּ בְּשִׂמְחָה וּבְשָׂשׂוֹן מוֹעֲדֵי קָדְשֶׁךָ, וְיִשְׂמְחוּ בְךָ יִשְׂרָאֵל מְקַדְּשֵׁי שְׁמֶךָ. בָּרוּךְ אַתָּה יהוה, מְקַדֵּשׁ יִשְׂרָאֵל וְהַזְּמַנִּים.","cond":["musaf","pesach"]},{"kind":"text","text":"אַתָּה בְחַרְתָּנוּ מִכָּל הָעַמִּים, אָהַבְתָּ אוֹתָנוּ וְרָצִיתָ בָּנוּ, וְרוֹמַמְתָּנוּ מִכָּל הַלְּשׁוֹנוֹת וְקִדַּשְׁתָּנוּ בְּמִצְוׂתֶיךָ, וְקֵרַבְתָּנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶךָ, וְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ עָלֵינוּ קָרָאתָ. וַתִּתֶּן לָנוּ יהוה אֱלֹהֵינוּ בְּאַהֲבָה מוֹעֲדִים לְשִׂמְחָה, חַגִּים וּזְמַנִּים לְשָׂשׂוֹן אֶת יוֹם","cond":["musaf","sucot"]},{"kind":"text","text":"חַג הַמַּצּוֹת הַזֶּה, זְמַן חֵרוּתֵנוּ","cond":["musaf","sucot","pesach"]},{"kind":"text","text":"חַג הַסֻּכּוֹת הַזֶּה, זְמַן שִׂמְחָתֵנוּ","cond":["musaf","sucot","sucot"]},{"kind":"text","text":"מִקְרָא קֹדֶשׁ, זֵכֶר לִיצִיאַת מִצְרָיִם.\n\nוּמִפְּנֵי חֲטָאֵינוּ גָּלִינוּ מֵאַרְצֵנוּ, וְנִתְרַחַקְנוּ מֵעַל אַדְמָתֵנוּ, וְאֵין אֲנַחְנוּ יְכוֹלִים לַעֲלוֹת וְלֵרָאוֹת וּלְהִשְׁתַּחֲווֹת לְפָנֶיךָ, וְלַעֲשׂוֹת חוֹבוֹתֵינוּ בְּבֵית בְּחִירָתֶךָ, בַּבַּיִת הַגָּדוֹל וְהַקָּדוֹשׁ שֶׁנִּקְרָא שִׁמְךָ עָלָיו, מִפְּנֵי הַיָּד שֶׁנִּשְׁתַּלְּחָה בְּמִקְדָּשֶׁךָ. יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן, שֶׁתָּשׁוּב וּתְרַחֵם עָלֵינוּ וְעַל מִקְדָּשְׁךָ בְּרַחֲמֶיךָ הָרַבִּים, וְתִבְנֵהוּ מְהֵרָה וּתְגַדֵּל כְּבוֹדוֹ. אָבִינוּ מַלְכֵּנוּ, גַּלֵּה כְּבוֹד מַלְכוּתְךָ עָלֵינוּ מְהֵרָה, וְהוֹפַע וְהִנָּשֵׂא עָלֵינוּ לְעֵינֵי כָּל חָי, וְקָרֵב פְּזוּרֵינוּ מִבֵּין הַגּוֹיִם, וּנְפוּצוֹתֵינוּ כַּנֵּס מִיַּרְכְּתֵי אָרֶץ. וַהֲבִיאֵנוּ לְצִיּוֹן עִירְךָ בְּרִנָּה, וְלִירוּשָׁלַיִם בֵּית מִקְדָּשְׁךָ בְּשִׂמְחַת עוֹלָם, וְשָׁם נַעֲשֶׂה לְפָנֶיךָ אֶת קָרְבְּנוֹת חוֹבוֹתֵינוּ תְּמִידִים כְּסִדְרָם וּמוּסָפִים כְּהִלְכָתָם, וְאֶת מוּסַף יוֹם","cond":["musaf","sucot"]},{"kind":"text","text":"חַג הַמַּצּוֹת הַזֶּה","cond":["musaf","sucot","pesach"]},{"kind":"text","text":"חַג הַסֻּכּוֹת הַזֶּה","cond":["musaf","sucot","sucot"]},{"kind":"text","text":"נַעֲשֶׂה וְנַקְרִיב לְפָנֶיךָ בְּאַהֲבָה כְּמִצְוַת רְצוֹנֶךָ, כְּמוֹ שֶׁכָּתַבְתָּ עָלֵינוּ בְּתוֹרָתֶךָ עַל יְדֵי מֹשֶׁה עַבְדֶּךָ מִפִּי כְבוֹדֶךָ, כָּאָמוּר:","cond":["musaf","sucot"]},{"kind":"text","text":"וְהִקְרַבְתֶּם אִשֶּׁה עֹלָה לַיהוה, פָּרִים בְּנֵי בָקָר שְׁנַיִם, וְאַיִל אֶחָד, וְשִׁבְעָה כְבָשִׂים בְּנֵי שָׁנָה, תְּמִימִם יִהְיוּ לָכֶם:\nוּמִנְחָתָם וְנִסְכֵּיהֶם כִּמְדֻבָּר: שְׁלֹשָׁה עֶשְׂרֹנִים לַפָּר, וּשְׁנֵי עֶשְׂרֹנִים לָאָיִל, וְעִשָּׂרוֹן לַכֶּבֶשׂ, וְיַיִן כְּנִסְכּוֹ, וְשָׂעִיר לְכַפֵּר, וּשְׁנֵי תְמִידִים כְּהִלְכָתָם.","cond":["musaf","sucot","pesach"]},{"kind":"text","text":":-:-","cond":["musaf","sucot","sucot"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן רַחֵם עָלֵינוּ, טוֹב וּמֵטִיב הִדָּרֶשׁ לָנוּ, שׁוּבָה אֵלֵינוּ בַּהֲמוֹן רַחֲמֶיךָ, בִּגְלַל אָבוֹת שֶׁעָשׂוּ רְצוֹנֶךָ. בְּנֵה בֵיתְךָ כְּבַתְּחִלָּה, וְכוֹנֵן מִקְדָּשְׁךָ עַל מְכוֹנוֹ, וְהַרְאֵנוּ בְּבִנְיָנוֹ וְשַׂמְּחֵנוּ בְּתִקּוּנוֹ, וְהָשֵׁב כֹּהֲנִים לַעֲבוֹדָתָם וּלְוִיִּם לְשִׁירָם וּלְזִמְרָם, וְהָשֵׁב יִשְׂרָאֵל לִנְוֵיהֶם. וְשָׁם נַעֲלֶה וְנֵרָאֶה וְנִשְׁתַּחֲוֶה לְפָנֶיךָ בְּשָׁלֹשׁ פַּעֲמֵי רְגָלֵינוּ כַּכָּתוּב בְּתוֹרָתֶךָ: שָׁלֹשׁ פְּעָמִים בַּשָּׁנָה יֵרָאֶה כָל זְכוּרְךָ אֶת פְּנֵי יהוה אֱלֹהֶיךָ בַּמָּקום אֲשֶׁר יִבְחָר, בְּחַג הַמַּצּוֹת, וּבְחַג הַשָּׁבֻעוֹת, וּבְחַג הַסֻּכּוֹת, וְלא יֵרָאֶה אֶת פְּנֵי יהוה רֵיקָם: אִישׁ כְּמַתְּנַת יָדוֹ, כְּבִרְכַּת יהוה אֱלֹהֶיךָ אֲשֶׁר נָתַן לָךְ:\n\nוְהַשִּׂיאֵנוּ יהוה אֱלֹהֵינוּ אֶת בִּרְכַּת מוֹעֲדֶיךָ, לְחַיִּים וּלְשָׁלוֹם, לְשִׂמְחָה וּלְשָׂשׂוֹן, כַּאֲשֶׁר רָצִיתָ וְאָמַרְתָּ לְבָרְכֵנוּ. קַדְּשֵׁנוּ בְּמִצְוׂתֶיךָ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתֶךָ, שַׂבְּעֵנוּ מִטּוּבֶךָ, וְשַׂמְּחֵנוּ בִּישׁוּעָתֶךָ, וְטַהֵר לִבֵּנוּ לְעָבְדְּךָ בֶּאֱמֶת, וְהַנְחִילֵנוּ יהוה אֱלֹהֵינוּ בְּשִׂמְחָה וּבְשָׂשׂוֹן מוֹעֲדֵי קָדְשֶׁךָ, וְיִשְׂמְחוּ בְךָ יִשְׂרָאֵל מְקַדְּשֵׁי שְׁמֶךָ. בָּרוּךְ אַתָּה יהוה, מְקַדֵּשׁ יִשְׂרָאֵל וְהַזְּמַנִּים.","cond":["musaf","sucot"]},{"kind":"text","text":"רְצֵה יהוה אֱלֹהֵינוּ בְּעַמְּךָ יִשְׂרָאֵל וְלִתְפִלָּתָם שְׁעֵה, וְהָשֵׁב אֶת הָעֲבוֹדָה לִדְבִיר בֵּיתֶךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם, מְהֵרָה בְּאַהֲבָה תְקַבֵּל בְּרָצוֹן. וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּךָ. וְתֶחֱזֶינָה עֵינֵינוּ בְּשׁוּבְךָ לְצִיּוֹן בְּרַחֲמִים. בָּרוּךְ אַתָּה יהוה, הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן.","cond":["musaf"]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שָׁאַתָּה הוּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ לְעוֹלָם וָעֵד. צוּר חַיֵּינוּ, מָגֵן יִשְׁעֵנוּ אַתָּה הוּא לְדוֹר וָדוֹר. נוֹדֶה לְּךָ וּנְסַפֵּר תְּהִלָּתֶךָ עַל חַיֵּינוּ הַמְּסוּרִים בְּיָדֶךָ, וְעַל נִשְׁמוֹתֵינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּיךָ שֶׁבְּכָל יוֹם עִמָּנוּ, וְעַל נִפְלְאוֹתֶיךָ וְטוֹבוֹתֶיךָ שֶׁבְּכָל עֵת, עֶרֶב וָבֹקֶר וְצָהֳרָיִם. הַטּוֹב כִּי לֹא כָלוּ רַחֲמֶיךָ, וְהַמְרַחֵם כִּי לֹא תַמּוּ חֲסָדֶיךָ, כִּי מֵעוֹלָם קִוִּינוּ לָךְ.","cond":["musaf"]},{"kind":"header","text":"מודים דרבנן","cond":["musaf"]},{"kind":"instruction","text":"מודים דרבנן:","cond":["musaf"]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שָׁאַתָּה הוּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי כָל בָּשָׂר, יוֹצְרֵנוּ יוֹצֵר בְּרֵאשִׁית, בְּרָכוֹת וְהוֹדָאוֹת לְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ עַל שֶׁהֶחֱיִיתָנוּ וְקִיַּמְתָּנוּ. כֵּן תְּחַיֵּנוּ וּתְקַיְּמֵנוּ, וְתֶאֱסוֹף גָּלֻיּוֹתֵינוּ לְחַצְרוֹת קָדְשֶׁךָ, לִשְׁמוֹר חֻקֶּיךָ, וְלַעֲשׂוֹת רְצוֹנֶךָ, וּלְעָבְדְךָ בְּלֵבָב שָׁלֵם, עַל שֶׁאֲנַחְנוּ מוֹדִים לָךְ. בָּרוּךְ אֵל הַהוֹדָאוֹת.","cond":["musaf"]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מַתִּתְיָהוּ בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְהַשְׁכִּיחָם תּוֹרָתֶךָ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנֶךָ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּטְמֵאִים בְּיַד טְהוֹרִים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, וּלְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמֶךָ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כֵּן בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ לְהוֹדוֹת וּלְהַלֵּל לְשִׁמְךָ הַגָּדוֹל. (נ\"א: וְקָבְעוּ שְׁמוֹנַת יָמִים אֵלּוּ בְּהַלֵּל וּבְהוֹדָאָה וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה.)","cond":["musaf","chanuka"]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים, מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ, וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ, וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְּרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ (, וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה).","cond":["musaf","purim"]},{"kind":"text","text":"וְעַל כֻּלָּם יִתְבָּרַךְ וְיִתְרוֹמַם וְיִתְנַשֵּׂא שִׁמְךָ מַלְכֵּנוּ תָּמִיד לְעוֹלָם וָעֶד.","cond":["musaf"]},{"kind":"special","text":"וּכְתֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶךָ.","cond":["musaf","ayt"]},{"kind":"text","text":"וְכֹל הַחַיִּים יוֹדוּךָ סֶלָה, וִיהַלְלוּ וִיבָרְכוּ אֶת שִׁמְךָ הַגָּדוֹל בֶּאֱמֶת לְעוֹלָם כִּי טוֹב, הָאֵל יְשׁוּעָתֵנוּ וְעֶזְרָתֵנוּ סֶלָה, הָאֵל הַטּוֹב. בָּרוּך אַתָּה יהוה, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת.","cond":["musaf"]},{"kind":"header","text":"ברכת כהנים","cond":["musaf"]},{"kind":"instruction","text":"ברכת כהנים לחזרת הש\"ץ:\n\nאם לא עלו כהנים לדוכן הש\"ץ אומר או\"א (נמצא בהמשך).\n\nאם עלו שני כהנים לדוכן קוראים להם - כֹּהֲנִים:\n\nהכהנים מברכים:","cond":["musaf"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בִּקְדֻשָּׁתוֹ שֶׁל אַהֲרֹן, וְצִוָּנוּ לְבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בְּאַהֲבָה.\n\nיְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ:\nיָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ:\nיִשָּׂא יהוה פָּנָיו אֵלֶיךָ וְיָשֵׂם לְךָ שָׁלוֹם:","cond":["musaf"]},{"kind":"instruction","text":"הקהל אומר:","cond":["musaf"]},{"kind":"text","text":"אַדִּיר בַּמָּרוֹם שׁוֹכֵן בִּגְבוּרָה, אַתָּה שָׁלוֹם וְשִׁמְךָ שָׁלוֹם. יְהִי רָצוֹן שֶׁתָּשִׂים עָלֵינוּ וְעַל כָּל עַמְּךָ בֵּית יִשְׂרָאֵל חַיִּים וּבְרָכָה לְמִשְׁמֶרֶת שָׁלוֹם.","cond":["musaf"]},{"kind":"instruction","text":"הכהנים אומרים","cond":["musaf"]},{"kind":"text","text":"רִבּוֹנוֹ שֶׁל עוֹלָם, עָשִׂינוּ מַה שֶּׁגָּזַרְתָּ עָלֵינוּ, אַף אַתָּה עֲשֵׂה עִמָּנוּ כְּמוֹ שֶׁהִבְטַחְתָּנוּ: הַשְׁקִיפָה מִמְּעוֹן קָדְשְׁךָ מִן הַשָּׁמַיִם, וּבָרֵךְ אֶת עַמְּךָ אֶת יִשְׂרָאֵל, וְאֵת הָאֲדָמָה אֲשֶׁר נָתַתָּה לָנוּ, כַּאֲשֶׁר נִשְׁבַּעְתָּ לַאֲבֹתֵינוּ, אֶרֶץ זָבַת חָלָב וּדְבָשׁ:","cond":["musaf"]},{"kind":"instruction","text":"אם לא עלו כהנים לדוכן הש\"ץ אומר:","cond":["musaf"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, בָּרְכֵנוּ בַּבְּרָכָה הַמְשֻׁלֶּשֶׁת בַּתּוֹרָה הַכְּתוּבָה עַל יְדֵי מֹשֶׁה עַבְדֶּךָ, הָאֲמוּרָה מִפִּי אַהֲרֹן וּבָנָיו כֹּהֲנִים עַם קְדוֹשֶׁךָ, כָּאָמוּר: יְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ: יָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ: יִשָּׂא יהוה פָּנָיו אֵלֶיךָ וְיָשֵׂם לְךָ שָׁלוֹם:","cond":["musaf"]},{"kind":"text","text":"שִׂים שָׁלוֹם טוֹבָה וּבְרָכָה, חַיִּים חֵן וָחֶסֶד וְרַחֲמִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל עַמֶּךָ. בָּרְכֵנוּ אָבִינוּ כֻּלָּנוּ כְּאֶחָד (יַחַד) בְּאוֹר פָּנֶיךָ, כִּי בְאוֹר פָּנֶיךָ נָתַתָּ לָּנוּ יהוה אֱלֹהֵינוּ תּוֹרַת חַיִּים וְאַהֲבַת חֶסֶד, וּצְדָקָה וּבְרָכָה וְרַחֲמִים וְחַיִּים וְשָׁלוֹם. וְטוֹב יִהְיֶה בְעֵינֶיךָ לְבָרְכֵנוּ וּלְבָרֵךְ אֶת כָּל עַמְּךָ יִשְׂרָאֵל בְּכָל עֵת וּבְכָל שָׁעָה בִּשְׁלוֹמֶךָ (בְּרֹב עֹז וְשָׁלוֹם).","cond":["musaf"]},{"kind":"special","text":"בְּסֵפֶר חַיִּים, בְּרָכָה וְשָׁלוֹם, וּפַרְנָסָה טוֹבָה, וּגְזֵרוֹת טוֹבוֹת, יְשׁוּעוֹת וְנֶחָמוֹת, נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ, אֲנַחְנוּ וְכָל עַמְּךָ בֵּית יִשְׂרָאֵל, לְחַיִּים טוֹבִים וּלְשָׁלוֹם.","cond":["musaf","ayt"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הַמְבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם.","cond":["musaf"]},{"kind":"text","text":"יִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:","cond":["musaf"]},{"kind":"instruction","text":"קדיש תתקבל","cond":["musaf"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":["musaf"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["musaf","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["musaf","ayt"]},{"kind":"text","text":"תִּתְקַבַּל צְלוֹתְהוֹן וּבָעוּתְהוֹן דְּכָל בֵּית יִשְׂרָאֵל קֳדָם אֲבוּהוֹן דִּי בִשְׁמַיָּא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":["musaf"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["musaf","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["musaf","ayt"]},{"kind":"header","text":"שיר של יום","cond":["shirShelYomAtEnd"]},{"kind":"instruction","text":"שיר של יום","cond":["shirShelYomAtEnd"]},{"kind":"text","text":"תְּפִלָּה לְדָוִד, הַטֵּה יהוה אָזְנְךָ עֲנֵנִי, כִּי עָנִי וְאֶבְיוֹן אָנִי: שָׁמְרָה נַפְשִׁי כִּי חָסִיד אָנִי, הוֹשַׁע עַבְדְּךָ, אַתָּה אֱלֹהַי, הַבּוֹטֵחַ אֵלֶיךָ: חָנֵּנִי אֲדֹנָי, כִּי אֵלֶיךָ אֶקְרָא כָּל הַיּוֹם: שַׂמֵּחַ נֶפֶשׁ עַבְדֶּךָ, כִּי אֵלֶיךָ אֲדֹנָי נַפְשִׁי אֶשָּׂא: כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ: הַאֲזִינָה יהוה תְּפִלָּתִי וְהַקְשִׁיבָה בְּקוֹל תַּחֲנוּנוֹתָי: בְּיוֹם צָרָתִי אֶקְרָאֶךָּ כִּי תַעֲנֵנִי: אֵין כָּמוֹךָ בָאֱלֹהִים, אֲדֹנָי, וְאֵין כְּמַעֲשֶׂיךָ: כָּל גּוֹיִם אֲשֶׁר עָשִׂיתָ יָבוֹאוּ וְיִשְׁתַּחֲווּ לְפָנֶיךָ, אֲדֹנָי, וִיכַבְּדוּ לִשְׁמֶךָ: כִּי גָדוֹל אַתָּה וְעֹשֵׂה נִפְלָאוֹת, אַתָּה אֱלֹהִים לְבַדֶּךָ: הוֹרֵנִי יהוה דַּרְכֶּךָ, אֲהַלֵּךְ בַּאֲמִתֶּךָ, יַחֵד לְבָבִי לְיִרְאָה שְׁמֶךָ: אוֹדְךָ אֲדֹנָי אֱלֹהַי בְּכָל לְבָבִי, וַאֲכַבְּדָה שִׁמְךָ לְעוֹלָם: כִּי חַסְדְּךָ גָּדוֹל עָלָי, וְהִצַּלְתָּ נַפְשִׁי מִשְּׁאוֹל תַּחְתִּיָּה: אֱלֹהִים, זֵדִים קָמוּ עָלַי, וַעֲדַת עָרִיצִים בִּקְשׁוּ נַפְשִׁי, וְלֹא שָׂמוּךָ לְנֶגְדָּם: וְאַתָּה אֲדֹנָי אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב חֶסֶד וֶאֱמֶת: פְּנֵה אֵלַי וְחָנֵּנִי, תְּנָה עֻזְּךָ לְעַבְדֶּךָ, וְהוֹשִׁיעָה לְבֶן אֲמָתֶךָ: עֲשֵׂה עִמִּי אוֹת לְטוֹבָה, וְיִרְאוּ שֹׂנְאַי וְיֵבֹשׁוּ, כִּי אַתָּה יהוה עֲזַרְתַּנִי וְנִחַמְתָּנִי:","cond":["shirShelYomAtEnd","shacharitTachanun"]},{"kind":"text","text":"בֵּית יַעֲקֹב, לְכוּ וְנֵלְכָה בְּאוֹר יהוה: כִּי כָּל הָעַמִּים יֵלְכוּ אִישׁ בְּשֵׁם אֱלֹהָיו, וַאֲנַחְנוּ נֵלֵךְ בְּשֵׁם יהוה אֱלֹהֵינוּ לְעוֹלָם וָעֶד: יְהִי יהוה אֱלֹהֵינוּ עִמָּנוּ כַּאֲשֶׁר הָיָה עִם אבוֹתֵינוּ, אַל יַעַזְבֵנוּ וְאַל יִטְּשֵׁנוּ: לְהַטּות לְבָבֵנוּ אֵלָיו, לָלֶכֶת בְּכָל דְּרָכָיו וְלִשְׁמֹר מִצְוׂתָיו וְחֻקָּיו וּמִשְׁפָּטָיו אֲשֶׁר צִוָּה אֶת אֲבֹתֵינוּ: וְיִהְיוּ דְבָרַי אֵלֶּה אֲשֶׁר הִתְחַנַּנְתִּי לִפְנֵי יהוה קְרֹבִים אֶל יהוה אֱלֹהֵינוּ יוֹמָם וָלָיְלָה, לַעֲשׂוֹת מִשְׁפַּט עַבְדּוֹ וּמִשְׁפַּט עַמּוֹ יִשְׂרָאֵל דְּבַר יוֹם בְּיוֹמוֹ: לְמַעַן דַּעַת כָּל עַמֵּי הָאָרֶץ כִּי יהוה הוּא הָאֱלֹהִים, אֵין עוד:\n\nשִׁיר הַמַּעֲלוֹת לְדָוִד, לוּלֵי יהוה שֶׁהָיָה לָנוּ יֹאמַר נָא יִשְׂרָאֵל: לוּלֵי יהוה שֶׁהָיָה לָנוּ בְּקוּם עָלֵינוּ אָדָם: אֲזַי חַיִּים בְּלָעוּנוּ בַּחֲרוֹת אַפָּם בָּנוּ: אֲזַי הַמַּיִם שְׁטָפוּנוּ נַחְלָה עָבַר עַל נַפְשֵׁנוּ: אֲזַי עָבַר עַל נַפְשֵׁנוּ הַמַּיִם הַזֵּידוֹנִים: בָּרוּךְ יהוה שֶׁלֹּא נְתָנָנוּ טֶרֶף לְשִׁנֵּיהֶם: נַפְשֵׁנוּ כְּצִפּוֹר נִמְלְטָה מִפַּח יוֹקְשִׁים, הַפַּח נִשְׁבָּר וַאֲנַחְנוּ נִמְלָטְנוּ: עֶזְרֵנוּ בְּשֵׁם יהוה, עֹשֵׂה שָׁמַיִם וָאָרֶץ:","cond":["shirShelYomAtEnd","lamnatzeach"]},{"kind":"text","text":"הַיּוֹם יוֹם רִאשׁוֹן בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["shirShelYomAtEnd","sun"]},{"kind":"text","text":"לְדָוִד מִזְמוֹר, לַיהוה הָאָרֶץ וּמְלוֹאָהּ, תֵּבֵל וְיֹשְׁבֵי בָהּ: כִּי הוּא עַל יַמִּים יְסָדָהּ, וְעַל נְהָרוֹת יְכוֹנְנֶהָ: מִי יַעֲלֶה בְהַר יהוה, וּמִי יָקוּם בִּמְקוֹם קָדְשׁוֹ: נְקִי כַפַּיִם וּבַר לֵבָב, אֲשֶׁר לֹא נָשָׂא לַשָּׁוְא נַפְשִׁי וְלֹא נִשְׁבַּע לְמִרְמָה: יִשָּׂא בְרָכָה מֵאֵת יהוה, וּצְדָקָה מֵאֱלֹהֵי יִשְׁעוֹ: זֶה דּוֹר דֹּרְשָׁיו, מְבַקְשֵׁי פָנֶיךָ יַעֲקֹב סֶלָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וְהִנָּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבוֹא מֶלֶךְ הַכָּבוֹד: מִי זֶה מֶלֶךְ הַכָּבוֹד, יהוה עִזּוּז וְגִבּוֹר, יהוה גִּבּוֹר מִלְחָמָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבֹא מֶלֶךְ הַכָּבוֹד: מִי הוּא זֶה מֶלֶךְ הַכָּבוֹד, יהוה צְבָאוֹת הוּא מֶלֶךְ הַכָּבוֹד סֶלָה:","cond":["shirShelYomAtEnd","sun"]},{"kind":"text","text":"הַיּוֹם יוֹם שֵׁנִי בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["shirShelYomAtEnd","mon"]},{"kind":"text","text":"שִׁיר מִזְמוֹר לִבְנֵי קֹרַח: גָּדוֹל יהוה וּמְהֻלָּל מְאֹד בְּעִיר אֱלֹהֵינוּ הַר קָדְשׁוֹ: יְפֵה נוֹף, מְשׂוֹשׂ כָּל הָאָרֶץ, הַר צִיּוֹן יַרְכְּתֵי צָפוֹן קִרְיַת מֶלֶךְ רָב: אֱלֹהִים בְּאַרְמְנוֹתֶיהָ נוֹדַע לְמִשְׂגָּב: כִּי הִנֵּה הַמְּלָכִים נוֹעֲדוּ עָבְרוּ יַחְדָּו: הֵמָּה רָאוּ כֵּן תָּמָהוּ, נִבְהֲלוּ נֶחְפָּזוּ: רְעָדָה אֲחָזָתַם שָׁם, חִיל כַּיּוֹלֵדָה: בְּרוּחַ קָדִים תְּשַׁבֵּר אֳנִיּוֹת תַּרְשִׁישׁ: כַּאֲשֶׁר שָׁמַעְנוּ כֵּן רָאִינוּ בְּעִיר יהוה צְבָאוֹת בְּעִיר אֱלֹהֵינוּ, אֱלֹהִים יְכוֹנְנֶהָ עַד עוֹלָם סֶלָה: דִּמִּינוּ אֱלֹהִים חַסְדֶּךָ בְּקֶרֶב הֵיכָלֶךָ: כְּשִׁמְךָ אֱלֹהִים כֵּן תְּהִלָּתְךָ עַל קַצְוֵי אֶרֶץ, צֶדֶק מָלְאָה יְמִינֶךָ: יִשְׂמַח הַר צִיּוֹן, תָּגֵלְנָה בְּנוֹת יְהוּדָה, לְמַעַן מִשְׁפָּטֶיךָ: סֹבּוּ צִיּוֹן וְהַקִּיפוּהָ, סִפְרוּ מִגְדָּלֶיהָ: שִׁיתוּ לִבְּכֶם לְחֵילָה, פַּסְּגוּ אַרְמְנוֹתֶיהָ, לְמַעַן תְּסַפְּרוּ לְדוֹר אַחֲרוֹן: כִּי זֶה אֱלֹהִים אֱלֹהֵינוּ עוֹלָם וָעֶד, הוּא יְנַהֲגֵנוּ עַל מוּת:","cond":["shirShelYomAtEnd","mon"]},{"kind":"text","text":"הַיּוֹם יוֹם שְׁלִישִׁי בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["shirShelYomAtEnd","tue"]},{"kind":"text","text":"מִזְמוֹר לְאָסָף, אֱלֹהִים נִצָּב בַּעֲדַת אֵל, בְּקֶרֶב אֱלֹהִים יִשְׁפֹּט: עַד מָתַי תִּשְׁפְּטוּ עָוֶל וּפְנֵי רְשָׁעִים תִּשְׂאוּ סֶלָה: שִׁפְטוּ דַל וְיָתוֹם, עָנִי וָרָשׁ הַצְדִּיקוּ: פַּלְּטוּ דַל וְאֶבְיוֹן, מִיַּד רְשָׁעִים הַצִּילוּ: לֹא יָדְעוּ וְלֹא יָבִינוּ, בַּחֲשֵׁכָה יִתְהַלָּכוּ, יִמּוֹטוּ כָּל מוֹסְדֵי אָרֶץ: אֲנִי אָמַרְתִּי אֱלֹהִים אַתֶּם וּבְנֵי עֶלְיוֹן כֻּלְּכֶם: אָכֵן כְּאָדָם תְּמוּתוּן וּכְאַחַד הַשָּׂרִים תִּפֹּלוּ: קוּמָה אֱלֹהִים שָׁפְטָה הָאָרֶץ, כִּי אַתָּה תִנְחַל בְּכָל הַגּוֹיִם:","cond":["shirShelYomAtEnd","tue"]},{"kind":"text","text":"הַיּוֹם יוֹם רְבִיעִי בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["shirShelYomAtEnd","wed"]},{"kind":"text","text":"אֵל נְקָמוֹת יהוה, אֵל נְקָמוֹת הוֹפִיעַ: הִנָּשֵׂא שֹׁפֵט הָאָרֶץ, הָשֵׁב גְּמוּל עַל גֵּאִים: עַד מָתַי רְשָׁעִים, יהוה, עַד מָתַי רְשָׁעִים יַעֲלֹזוּ: יַבִּיעוּ יְדַבְּרוּ עָתָק, יִתְאַמְּרוּ כָּל פֹעֲלֵי אָוֶן: עַמְּךָ יהוה יְדַכְּאוּ, וְנַחֲלָתְךָ יְעַנּוּ: אַלְמָנָה וְגֵר יַהֲרֹגוּ, וִיתוֹמִים יְרַצֵּחוּ: וַיֹּאמְרוּ לֹא יִרְאֶה יָהּ, וְלֹא יָבִין אֱלֹהֵי יַעֲקֹב: בִּינוּ בֹּעֲרִים בָּעָם, וּכְסִילִים מָתַי תַּשְׂכִּילוּ: הַנֹּטַע אֹזֶן הֲלֹא יִשְׁמָע, אִם יֹצֵר עַיִן הֲלֹא יַבִּיט: הֲיֹסֵר גּוֹיִם הֲלֹא יוֹכִיחַ, הַמְלַמֵּד אָדָם דָּעַת: יהוה יֹדֵעַ מַחְשְׁבוֹת אָדָם כִּי הֵמָּה הָבֶל: אַשְׁרֵי הַגֶּבֶר אֲשֶׁר תְּיַסְּרֶנּוּ יָּהּ, וּמִתּוֹרָתְךָ תְלַמְּדֶנּוּ: לְהַשְׁקִיט לוֹ מִימֵי רָע, עַד יִכָּרֶה לָרָשָׁע שָׁחַת: כִּי לֹא יִטֹּשׁ יהוה עַמּוֹ, וְנַחֲלָתוֹ לֹא יַעֲזֹב: כִּי עַד צֶדֶק יָשׁוּב מִשְׁפָּט, וְאַחֲרָיו כָּל יִשְׁרֵי לֵב: מִי יָקוּם לִי עִם מְרֵעִים, מִי יִתְיַצֵּב לִי עִם פֹּעֲלֵי אָוֶן: לוּלֵי יהוה עֶזְרָתָה לִּי, כִּמְעַט שָׁכְנָה דוּמָה נַפְשִׁי: אִם אָמַרְתִּי מָטָה רַגְלִי, חַסְדְּךָ יהוה יִסְעָדֵנִי: בְּרֹב שַׂרְעַפַּי בְּקִרְבִּי, תַּנְחוּמֶיךָ יְשַׁעַשְׁעוּ נַפְשִׁי: הַיְחָבְרְךָ כִּסֵּא הַוּוֹת, יֹצֵר עָמָל עֲלֵי חֹק: יָגוֹדּוּ עַל נֶפֶשׁ צַדִּיק, וְדָם נָקִי יַרְשִׁיעוּ: וַיְהִי יהוה לִי לְמִשְׂגָּב, וֵאלֹהַי לְצוּר מַחְסִי: וַיָּשֶׁב עֲלֵיהֶם אֶת אוֹנָם וּבְרָעָתָם יַצְמִיתֵם, יַצְמִיתֵם יהוה אֱלֹהֵינוּ:\nלְכוּ נְרַנְּנָה לַיהוה, נָרִיעָה לְצוּר יִשְׁעֵנוּ: נְקַדְּמָה פָנָיו בְּתוֹדָה, בִּזְמִרוֹת נָרִיעַ לוֹ: כִּי אֵל גָּדוֹל יהוה, וּמֶלֶךְ גָּדוֹל עַל כָּל אֱלֹהִים:","cond":["shirShelYomAtEnd","wed"]},{"kind":"text","text":"הַיּוֹם יוֹם חֲמִישִׁי בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["shirShelYomAtEnd","thu"]},{"kind":"text","text":"לַמְנַצֵּחַ עַל הַגִּתִּית לְאָסָף: הַרְנִינוּ לֵאלֹהִים עֻזֵּנוּ, הָרִיעוּ לֵאלֹהֵי יַעֲקֹב: שְׂאוּ זִמְרָה וּתְנוּ תֹף, כִּנּוֹר נָעִים עִם נָבֶל: תִּקְעוּ בַחֹדֶשׁ שׁוֹפָר, בַּכֵּסֶה לְיוֹם חַגֵּנוּ: כִּי חֹק לְיִשְׂרָאֵל הוּא, מִשְׁפָּט לֵאלֹהֵי יַעֲקֹב: עֵדוּת בִּיהוֹסֵף שָׂמוֹ בְּצֵאתוֹ עַל אֶרֶץ מִצְרָיִם, שְׂפַת לֹא יָדַעְתִּי אֶשְׁמָע: הֲסִירוֹתִי מִסֵּבֶל שִׁכְמוֹ, כַּפָּיו מִדּוּד תַּעֲבֹרְנָה: בַּצָּרָה קָרָאתָ וָאֲחַלְּצֶךָּ, אֶעֶנְךָ בְּסֵתֶר רַעַם, אֶבְחָנְךָ עַל מֵי מְרִיבָה סֶלָה: שְׁמַע עַמִּי וְאָעִידָה בָּךְ, יִשְׂרָאֵל אִם תִּשְׁמַע לִי: לֹא יִהְיֶה בְךָ אֵל זָר, וְלֹא תִשְׁתַּחֲוֶה לְאֵל נֵכָר: אָנֹכִי יהוה אֱלֹהֶיךָ הַמַּעַלְךָ מֵאֶרֶץ מִצְרָיִם, הַרְחֶב פִּיךָ וַאֲמַלְאֵהוּ: וְלֹא שָׁמַע עַמִּי לְקוֹלִי, וְיִשְׂרָאֵל לֹא אָבָה לִי: וָאֲשַׁלְּחֵהוּ בִּשְׁרִירוּת לִבָּם, יֵלְכוּ בְּמוֹעֲצוֹתֵיהֶם: לוּ עַמִּי שֹׁמֵעַ לִי, יִשְׂרָאֵל בִּדְרָכַי יְהַלֵּכוּ: כִּמְעַט אוֹיְבֵיהֶם אַכְנִיעַ, וְעַל צָרֵיהֶם אָשִׁיב יָדִי: מְשַׂנְאֵי יהוה יְכַחֲשׁוּ לוֹ, וִיהִי עִתָּם לְעוֹלָם: וַיַּאֲכִילֵהוּ מֵחֵלֶב חִטָּה, וּמִצּוּר, דְּבַשׁ אַשְׂבִּיעֶךָ:","cond":["shirShelYomAtEnd","thu"]},{"kind":"text","text":"הַיּוֹם יוֹם שִׁשִּׁי בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["shirShelYomAtEnd","fri"]},{"kind":"text","text":"יהוה מָלָךְ גֵּאוּת לָבֵשׁ, לָבֵשׁ יהוה עֹז הִתְאַזָּר, אַף תִּכּוֹן תֵּבֵל בַּל תִּמּוֹט: נָכוֹן כִּסְאֲךָ מֵאָז, מֵעוֹלָם אָתָּה: נָשְׂאוּ נְהָרוֹת, יהוה, נָשְׂאוּ נְהָרוֹת קוֹלָם, יִשְׂאוּ נְהָרוֹת דָכְיָם: מִקֹּלוֹת מַיִם רַבִּים, אַדִּירִים מִשְׁבְּרֵי יָם, אַדִּיר בַּמָּרוֹם יהוה: עֵדֹתֶיךָ נֶאֶמְנוּ מְאֹד לְבֵיתְךָ נַאֲוָה קֹדֶשׁ, יהוה, לְאֹרֶךְ יָמִים:","cond":["shirShelYomAtEnd","fri"]},{"kind":"special","text":"בָּרְכִי נַפְשִׁי אֶת יהוה, יהוה אֱלֹהַי גָּדַלְתָּ מְּאֹד, הוֹד וְהָדָר לָבָשְׁתָּ:\nעֹטֶה אוֹר כַּשַּׂלְמָה נוֹטֶה שָׁמַיִם כַּיְרִיעָה:\nהַמְקָרֶה בַמַּיִם עֲלִיּוֹתָיו, הַשָּׂם עָבִים רְכוּבוֹ, הַמְהַלֵּךְ עַל כַּנְפֵי רוּחַ:\nעֹשֶׂה מַלְאָכָיו רוּחוֹת, מְשָׁרְתָיו אֵשׁ לֹהֵט:\nיָסַד אֶרֶץ עַל מְכוֹנֶיהָ, בַּל תִּמּוֹט עוֹלָם וָעֶד:\nתְּהוֹם כַּלְּבוּשׁ כִּסִּיתוֹ, עַל הָרִים יַעַמְדוּ מָיִם:\nמִן גַּעֲרָתְךָ יְנוּסוּן, מִן קוֹל רַעַמְךָ יֵחָפֵזוּן:\nיַעֲלוּ הָרִים, יֵרְדוּ בְקָעוֹת, אֶל מְקוֹם זֶה יָסַדְתָּ לָהֶם:\nגְּבוּל שַׂמְתָּ בַּל יַעֲבֹרוּן, בַּל יְשׁוּבוּן לְכַסּוֹת הָאָרֶץ:\nהַמְשַׁלֵּחַ מַעְיָנִים בַּנְּחָלִים בֵּין הָרִים יְהַלֵּכוּן:","cond":["shirShelYomAtEnd","rh"]},{"kind":"special","text":"יַשְׁקוּ כָּל חַיְתוֹ שָׂדָי, יִשְׁבְּרוּ פְרָאִים צְמָאָם:\nעֲלֵיהֶם עוֹף הַשָּׁמַיִם יִשְׁכּוֹן, מִבֵּין עֳפָאיִם יִתְּנוּ קוֹל:\nמַשְׁקֶה הָרִים מֵעֲלִיּוֹתָיו, מִפְּרִי מַעֲשֶׂיךָ תִּשְׂבַּע הָאָרֶץ:\nמַצְמִיחַ חָצִיר לַבְּהֵמָה וְעֵשֶׂב לַעֲבֹדַת הָאָדָם, לְהוֹצִיא לֶחֶם מִן הָאָרֶץ:\nוְיַיִן יְשַׂמַּח לְבַב אֱנוֹשׁ, לְהַצְהִיל פָּנִים מִשָּׁמֶן, וְלֶחֶם לְבַב אֱנוֹשׁ יִסְעָד:\nיִשְׂבְּעוּ עֲצֵי יהוה, אַרְזֵי לְבָנוֹן אֲשֶׁר נָטָע:\nאֲשֶׁר שָׁם צִפֳּרִים יְקַנֵּנוּ, חֲסִידָה בְּרוֹשִׁים בֵּיתָהּ:\nהָרִים הַגְּבֹהִים לַיְּעֵלִים, סְלָעִים מַחְסֶה לַשְׁפַנִּים:\nעָשָׂה יָרֵחַ לְמוֹעֲדִים, שֶׁמֶשׁ יָדַע מְבוֹאוֹ:\nתָּשֶׁת חֹשֶׁךְ וִיהִי לָיְלָה, בּוֹ תִרְמֹשׂ כָּל חַיְתוֹ יָעַר:\nהַכְּפִירִים שֹׁאֲגִים לַטָּרֶף וּלְבַקֵּשׁ מֵאֵל אָכְלָם:\nתִּזְרַח הַשֶּׁמֶשׁ יֵאָסֵפוּן וְאֶל מְעוֹנֹתָם יִרְבָּצוּן:","cond":["shirShelYomAtEnd","rh"]},{"kind":"special","text":"יֵצֵא אָדָם לְפָעֳלוֹ וְלַעֲבֹדָתוֹ עֲדֵי עָרֶב:\nמָה רַבּוּ מַעֲשֶׂיךָ יהוה, כֻּלָּם בְּחָכְמָה עָשִׂיתָ, מָלְאָה הָאָרֶץ קִנְיָנֶךָ:\nזֶה הַיָּם גָּדוֹל וּרְחַב יָדָיִם, שָׁם רֶמֶשׂ וְאֵין מִסְפָּר, חַיּוֹת קְטַנּוֹת עִם גְּדֹלוֹת:\nשָׁם אֳנִיּוֹת יְהַלֵּכוּן, לִוְיָתָן זֶה יָצַרְתָּ לְשַׂחֶק בּוֹ:\nכֻּלָּם אֵלֶיךָ יְשַׂבֵּרוּן לָתֵת אָכְלָם בְּעִתּוֹ:\nתִּתֵּן לָהֶם יִלְקֹטוּן, תִּפְתַּח יָדְךָ יִשְׂבְּעוּן טוֹב:\nתַּסְתִּיר פָּנֶיךָ יִבָּהֵלוּן, תֹּסֵף רוּחָם יִגְוָעוּן וְאֶל עֲפָרָם יְשׁוּבוּן:\nתְּשַׁלַּח רוּחֲךָ יִבָּרֵאוּן וּתְחַדֵּשׁ פְּנֵי אֲדָמָה:\nיְהִי כְבוֹד יהוה לְעוֹלָם, יִשְׂמַח יהוה בְּמַעֲשָׂיו:\nהַמַּבִּיט לָאָרֶץ וַתִּרְעָד, יִגַּע בֶּהָרִים וְיֶעֱשָׁנוּ:\nאָשִׁירָה לַיהוה בְּחַיָּי, אֲזַמְּרָה לֵאלֹהַי בְּעוֹדִי:\nיֶעֱרַב עָלָיו שִׂיחִי, אָנֹכִי אֶשְׂמַח בַּיהוה:\nיִתַּמּוּ חַטָּאִים מִן הָאָרֶץ וּרְשָׁעִים עוֹד אֵינָם, בָּרְכִי נַפְשִׁי אֶת יהוה, הַלְלוּיָהּ:","cond":["shirShelYomAtEnd","rh"]},{"kind":"header","text":"הושיענו","cond":["shirShelYomAtEnd"]},{"kind":"instruction","text":"בכל יום אחרי שיר של יום אומרים:","cond":["shirShelYomAtEnd"]},{"kind":"text","text":"הוֹשִׁיעֵנוּ יהוה אֱלֹהֵינוּ וְקַבְּצֵנוּ מִן הַגּוֹיִם, לְהֹדוֹת לְשֵׁם קָדְשֶׁךָ לְהִשְׁתַּבֵּחַ בִּתְהִלָּתֶךָ: בָּרוּךְ יהוה אֱלֹהֵי יִשְׂרָאֵל מִן הָעוֹלָם וְעַד הָעוֹלָם, וְאָמַר כָּל הָעָם אָמֵן הַלְלוּיָהּ: בָּרוּךְ יהוה מִצִּיּוֹן, שֹׁכֵן יְרוּשָׁלִָם הַלְלוּיָהּ: בָּרוּךְ יהוה אֱלֹהִים אֱלֹהֵי יִשְׂרָאֵל, עֹשֵׂה נִפְלָאוֹת לְבַדּוֹ: וּבָרוּךְ שֵׁם כְּבוֹדוֹ לְעוֹלָם, וְיִמָּלֵא כְבוֹדוֹ אֶת כָּל הָאָרֶץ, אָמֵן וְאָמֵן:","cond":["shirShelYomAtEnd"]},{"kind":"instruction","text":"קדיש יתום","cond":["shirShelYomAtEnd"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":["shirShelYomAtEnd"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["shirShelYomAtEnd","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["shirShelYomAtEnd","ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":["shirShelYomAtEnd"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["shirShelYomAtEnd","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["shirShelYomAtEnd","ayt"]},{"kind":"header","text":"מזמור לבית האבל","cond":["shirShelYomAtEnd"]},{"kind":"instruction","text":"בבית האבל אומרים מזמור זה:","cond":["shirShelYomAtEnd","shacharitTachanun"]},{"kind":"text","text":"לַמְנַצֵּחַ לִבְנֵי קֹרַח מִזְמוֹר: שִׁמְעוּ זֹאת כָּל הָעַמִּים, הַאֲזִינוּ כָּל יֹשְׁבֵי חָלֶד: גַּם בְּנֵי אָדָם, גַּם בְּנֵי אִישׁ, יַחַד עָשִׁיר וְאֶבְיוֹן: פִּי יְדַבֵּר חָכְמוֹת, וְהָגוּת לִבִּי תְבוּנוֹת: אַטֶּה לְמָשָׁל אָזְנִי, אֶפְתַּח בְּכִנּוֹר חִידָתִי: לָמָּה אִירָא בִּימֵי רָע, עֲוׂן עֲקֵבַי יְסוּבֵּנִי: הַבֹּטְחִים עַל חֵילָם, וּבְרֹב עָשְׁרָם יִתְהַלָּלוּ: אָח לֹא פָדֹה יִפְדֶּה אִישׁ, לֹא יִתֵּן לֵאלֹהִים כָּפְרוֹ: וְיֵקַר פִּדְיוֹן נַפְשָׁם, וְחָדַל לְעוֹלָם: וִיחִי עוֹד לָנֶצַח, לֹא יִרְאֶה הַשָּׁחַת: כִּי יִרְאֶה חֲכָמִים יָמוּתוּ, יַחַד כְּסִיל וָבַעַר יֹאבֵדוּ, וְעָזְבוּ לַאֲחֵרִים חֵילָם: קִרְבָּם בָּתֵּימוֹ לְעוֹלָם, מִשְׁכְּנֹתָם לְדֹר וָדֹר, קָרְאוּ בִשְׁמוֹתָם עֲלֵי אֲדָמוֹת: וְאָדָם בִּיקָר בַּל יָלִין, נִמְשַׁל כַּבְּהֵמוֹת נִדְמוּ: זֶה דַרְכָּם כֵּסֶל לָמוֹ, וְאַחֲרֵיהֶם בְּפִיהֶם יִרְצוּ סֶלָה: כַּצֹּאן לִשְׁאוֹל שַׁתּוּ מָוֶת יִרְעֵם, וַיִּרְדּוּ בָם יְשָׁרִים לַבֹּקֶר, וְצוּרָם לְבַלּוֹת שְׁאוֹל מִזְּבֻל לוֹ: אַךְ אֱלֹהִים יִפְדֶּה נַפְשִׁי מִיַּד שְׁאוֹל, כִּי יִקָּחֵנִי סֶלָה: אַל תִּירָא כִּי יַעֲשִׁר אִישׁ, כִּי יִרְבֶּה כְּבוֹד בֵּיתוֹ: כִּי לֹא בְמוֹתוֹ יִקַּח הַכֹּל, לֹא יֵרֵד אַחֲרָיו כְּבוֹדוֹ: כִּי נַפְשׁוֹ בְּחַיָּיו יְבָרֵךְ, וְיוֹדֻךָ כִּי תֵיטִיב לָךְ: תָּבוֹא עַד דּוֹר אֲבוֹתָיו, עַד נֵצַח לֹא יִרְאוּ אוֹר: אָדָם בִּיקָר וְלֹא יָבִין נִמְשַׁל כַּבְּהֵמוֹת נִדְמוּ:","cond":["shirShelYomAtEnd","shacharitTachanun"]},{"kind":"instruction","text":"בבית האבל אומרים מזמור זה:","cond":["shirShelYomAtEnd","noShacharitTachanun"]},{"kind":"text","text":"מִכְתָּם לְדָוִד, שָׁמְרֵנִי אֵל כִּי חָסִיתִי בָךְ: אָמַרְתְּ לַיהוה, אֲדֹנָי אָתָּה, טוֹבָתִי בַּל עָלֶיךָ: לִקְדוֹשִׁים אֲשֶׁר בָּאָרֶץ הֵמָּה, וְאַדִּירֵי כָּל חֶפְצִי בָם: יִרְבּוּ עַצְּבוֹתָם אַחֵר מָהָרוּ, בַּל אַסִּיךְ נִסְכֵּיהֶם מִדָּם, וּבַל אֶשָּׂא אֶת שְׁמוֹתָם עַל שְׂפָתָי: יהוה, מְנָת חֶלְקִי וְכוֹסִי, אַתָּה תּוֹמִיךְ גּוֹרָלִי: חֲבָלִים נָפְלוּ לִי בַּנְּעִמִים, אַף נַחֲלָת שָׁפְרָה עָלָי: אֲבָרֵךְ אֶת יהוה אֲשֶׁר יְעָצָנִי, אַף לֵילוֹת יִסְּרוּנִי כִלְיוֹתָי: שִׁוִּיתִי יהוה לְנֶגְדִּי תָמִיד, כִּי מִימִינִי בַּל אֶמּוֹט: לָכֵן שָׂמַח לִבִּי וַיָּגֶל כְּבוֹדִי, אַף בְּשָׂרִי יִשְׁכֹּן לָבֶטַח: כִּי לֹא תַעֲזֹב נַפְשִׁי לִשְׁאוֹל, לֹא תִתֵּן חֲסִידְךָ לִרְאוֹת שָׁחַת: תּוֹדִיעֵנִי אֹרַח חַיִּים, שֹׂבַע שְׂמָחוֹת אֶת פָּנֶיךָ, נְעִמוֹת בִּימִינְךָ נֶצַח:","cond":["shirShelYomAtEnd","noShacharitTachanun"]},{"kind":"instruction","text":"קדיש יתום","cond":["shirShelYomAtEnd"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":["shirShelYomAtEnd"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["shirShelYomAtEnd","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["shirShelYomAtEnd","ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":["shirShelYomAtEnd"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["shirShelYomAtEnd","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["shirShelYomAtEnd","ayt"]},{"kind":"header","text":"לדוד","cond":["shirShelYomAtEnd","ledavid"]},{"kind":"special","text":"לְדָוִד, יהוה אוֹרִי וְיִשְׁעִי מִמִּי אִירָא, יהוה מָעוֹז חַיַּי מִמִּי אֶפְחָד: בִּקְרֹב עָלַי מְרֵעִים לֶאֱכֹל אֶת בְּשָׂרִי, צָרַי וְאֹיְבַי לִי, הֵמָּה כָשְׁלוּ וְנָפָלוּ: אִם תַּחֲנֶה עָלַי מַחֲנֶה לֹא יִירָא לִבִּי, אִם תָּקוּם עָלַי מִלְחָמָה בְּזֹאת אֲנִי בוֹטֵחַ: אַחַת שָׁאַלְתִּי מֵאֵת יהוה, אוֹתָהּ אֲבַקֵּשׁ, שִׁבְתִּי בְּבֵית יהוה כָּל יְמֵי חַיַּי, לַחֲזוֹת בְּנֹעַם יהוה וּלְבַקֵּר בְּהֵיכָלוֹ: כִּי יִצְפְּנֵנִי בְּסֻכֹּה בְּיוֹם רָעָה יַסְתִּירֵנִי בְּסֵתֶר אָהֳלוֹ, בְּצוּר יְרוֹמְמֵנִי: וְעַתָּה יָרוּם רֹאשִׁי עַל אֹיְבַי סְבִיבוֹתַי, וְאֶזְבְּחָה בְאָהֳלוֹ זִבְחֵי תְרוּעָה, אָשִׁירָה וַאֲזַמְּרָה לַיהוה: שְׁמַע יהוה קוֹלִי אֶקְרָא, וְחָנֵּנִי וַעֲנֵנִי: לְךָ אָמַר לִבִּי בַּקְּשׁוּ פָנַי, אֶת פָּנֶיךָ יהוה אֲבַקֵּשׁ: אַל תַּסְתֵּר פָּנֶיךָ מִמֶּנִּי, אַל תַּט בְּאַף עַבְדֶּךָ, עֶזְרָתִי הָיִיתָ, אַל תִּטְּשֵׁנִי וְאַל תַּעַזְבֵנִי אֱלֹהֵי יִשְׁעִי: כִּי אָבִי וְאִמִּי עֲזָבוּנִי, וַיהוה יַאַסְפֵנִי: הוֹרֵנִי יהוה דַּרְכֶּךָ וּנְחֵנִי בְּאֹרַח מִישׁוֹר לְמַעַן שׁוֹרְרָי: אַל תִּתְּנֵנִי בְּנֶפֶשׁ צָרָי, כִּי קָמוּ בִי עֵדֵי שֶׁקֶר וִיפֵחַ חָמָס: לוּלֵא הֶאֱמַנְתִּי לִרְאוֹת בְּטוּב יהוה בְּאֶרֶץ חַיִּים: קַוֵּה אֶל יהוה, חֲזַק וְיַאֲמֵץ לִבֶּךָ, וְקַוֵּה אֶל יהוה:","cond":["shirShelYomAtEnd","ledavid"]},{"kind":"instruction","text":"קדיש יתום","cond":["shirShelYomAtEnd","ledavid"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":["shirShelYomAtEnd","ledavid"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["shirShelYomAtEnd","ledavid","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["shirShelYomAtEnd","ledavid","ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":["shirShelYomAtEnd","ledavid"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["shirShelYomAtEnd","ledavid","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["shirShelYomAtEnd","ledavid","ayt"]},{"kind":"instruction","text":"סיום התפילה","cond":["noTishaaBeav"]},{"kind":"text","text":"קַוֵּה אֶל יהוה, חֲזַק וְיַאֲמֵץ לִבֶּךָ, וְקַוֵּה אֶל יהוה:\nאֵין קָדושׁ כַּיהוה, כִּי אֵין בִּלְתֶּךָ, וְאֵין צוּר כֵּאלֹהֵינוּ:\nכִּי מִי אֱלוֹהַּ מִבַּלְעֲדֵי יהוה, וּמִי צוּר זוּלָתִי אֱלֹהֵינוּ:\n\nאֵין כֵּאלֹהֵינוּ, אֵין כַּאדוֹנֵינוּ, אֵין כְּמַלְכֵּנוּ, אֵין כְּמוֹשִׁיעֵנוּ.\nמִי כֵאלֹהֵינוּ, מִי כַאדוֹנֵינוּ, מִי כְמַלְכֵּנוּ, מִי כְמוֹשִׁיעֵנוּ.\nנוֹדֶה לֵאלֹהֵינוּ, נוֹדֶה לַאדוֹנֵינוּ, נוֹדֶה לְמַלְכֵּנוּ, נוֹדֶה לְמוֹשִׁיעֵנוּ.\nבָּרוּךְ אֱלֹהֵינוּ, בָּרוּךְ אֲדוֹנֵינוּ, בָּרוּךְ מַלְכֵּנוּ, בָּרוּךְ מוֹשִׁיעֵנוּ.\nאַתָּה הוּא אֱלֹהֵינוּ, אַתָּה הוּא אֲדוֹנֵינוּ, אַתָּה הוּא מַלְכֵּנוּ, אַתָּה הוּא מוֹשִׁיעֵנוּ. אַתָּה תוֹשִׁיעֵנוּ.\nאַתָּה תָקוּם תְּרַחֵם צִיּון כִּי עֵת לְחֶנְנָהּ כִּי בָא מועֵד:","cond":["noTishaaBeav"]},{"kind":"instruction","text":"פיטום הקטורת","cond":["noTishaaBeav"]},{"kind":"text","text":"פִּטּוּם הַקְּטֹרֶת: הַצֳּרִי, וְהַצִּפֹּרֶן, הַחֶלְבְּנָה, וְהַלְּבוֹנָה, מִשְׁקַל שִׁבְעִים שִׁבְעִים מָנֶה, מֹר וּקְצִיעָה, שִׁבֹּלֶת נֵרְדְּ, וְכַרְכֹּם מִשְׁקַל שִׁשָּׁה עָשָׂר שִׁשָּׁה עָשָׂר מָנֶה, הַקֹּשְׁטְ שְׁנֵים עָשָׂר, וְקִלּוּפָה שְׁלֹשָׁה, וְקִנָּמוֹן תִּשְׁעָה, בֹּרִית כַּרְשִׁינָה תִּשְׁעָה קַבִּין. יֵין קַפְרִיסִין סְאִין תְּלָתָא וְקַבִּין תְּלָתָא, וְאִם אֵין לוֹ יֵין קַפְרִיסִין מֵבִיא חֲמַר חִוַּרִין עַתִּיק. מֶלַח סְדוֹמִית רֹבַע, מַעֲלֶה עָשָׁן כָּל שֶׁהוּא, רַבִּי נָתָן הַבַּבְלִי אוֹמֵר: אַף כִּפַּת הַיַּרְדֵּן כָּל שֶׁהוּא. וְאִם נָתַן בָּהּ דְּבַשׁ פְּסָלָהּ, וְאִם חִסַּר אַחַת מִכָּל סַמָּנֶיהָ חַיָּב מִיתָה.\n\nרַבָּן שִׁמְעוֹן בֶּן גַּמְלִיאֵל אוֹמֵר: הַצֳּרִי אֵינוֹ אֶלָּא שְׂרָף הַנּוֹטֵף מֵעֲצֵי הַקְּטָף. בֹּרִית כַּרְשִׁינָה שֶׁשָּׁפִין בָּהּ אֶת הַצִּפֹּרֶן כְּדֵי שֶׁתְּהֵא נָאָה, יֵין קַפְרִיסִין שֶׁשּׁוֹרִין בּוֹ אֶת הַצִּפֹּרֶן כְּדֵי שֶׁתְּהֵא עַזָּה. וַהֲלֹא מֵי רַגְלַיִם יָפִין לָהּ, אֶלָּא שֶׁאֵין מַכְנִיסִין מֵי רַגְלַיִם בַּמִקְדָּשׁ מִפְּנֵי הַכָּבוֹד.\n\nתַּנְיָא: רַבִּי נָתָן אוֹמֵר: כְּשֶׁהוּא שׁוֹחֵק אוֹמֵר: \"הָדֵק הֵיטֵב, הֵיטֵב הָדֵק\", מִפְּנֵי שֶׁהַקּול יָפֶה לַבְּשמִים. פִּטְּמָהּ לַחֲצָאִין כְּשֵׁרָה. לִשְׁלִישׁ וְלִרְבִיעַ לֹא שָׁמַעְנוּ. אָמַר רַבִּי יְהוּדָה: זֶה הַכְּלָל: אִם כְּמִדָּתָהּ כְּשֵׁרָה לַחֲצָאִין. וְאִם חִסַּר אַחַת מִכָּל סַמָּנֶיהָ חַיָּב מִיתָה.\n\nתַּנְיָא: בַּר קַפָּרָא אוֹמֵר: אַחַת לְשִׁשִּׁים אוֹ לְשִׁבְעִים שָׁנָה הָיְתָה בָאָה שֶׁל שִׁירַיִם לַחֲצָאִין. וְעוֹד תָּנֵי בַּר קַפָּרָא: אִלּוּ הָיָה נוֹתֵן בָּהּ קוֹרְטוֹב שֶׁל דְּבַשׁ אֵין אָדָם יָכוֹל לַעֲמוֹד מִפְּנֵי רֵיחָהּ, וְלָמָה אֵין מְעָרְבִין בָּהּ דְּבַשׁ? מִפְּנֵי שֶׁהַתּוֹרָה אָמְרָה \"כִּי כָל שְׂאֹר וְכָל דְּבַשׁ לֹא תַקְטִירוּ מִמֶּנּוּ אִשֶּׁה לַיהוה:\"\n\nיהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה:\nיהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה:\nיהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה:\n\nיהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ:\nיהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ:\nיהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ:\n\nיהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:\nיהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:\nיהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:\n\nאַתָּה סֵתֶר לִי מִצַּר תִּצְּרֵנִי רָנֵּי פַלֵּט תְּסוֹבְבֵנִי סֶלָה:\nוְעָרְבָה לַיהוה מִנְחַת יְהוּדָה וִירוּשָׁלָיִם כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמוֹנִיּוֹת:\n\nתָּנָא דְבֵי אֵלִיָּהוּ: כָּל הַשּׁוֹנֶה הֲלָכוֹת בְּכָל יוֹם מֻבְטָח לוֹ שֶׁהוּא בֶּן עוֹלָם הַבָּא, שֶׁנֶּאֱמַר: הֲלִיכוֹת עוֹלָם לוֹ: אַל תִּקְרֵי הֲלִיכות אֶלָּא הֲלָכוֹת. אָמַר רַבִּי אֶלְעָזָר אָמַר רַבִּי חֲנִינָא: תַּלְמִידֵי חֲכָמִים מַרְבִּים שָׁלוֹם בָּעוֹלָם, שֶׁנֶּאֱמַר: וְכָל בָּנַיִךְ לִמּוּדֵי יהוה וְרַב שְׁלוֹם בָּנָיִךְ: אַל תִּקְרֵי בָּנָיִךְ אֶלָּא בּוֹנָיִךְ. שָׁלוֹם רָב לְאֹהֲבֵי תוֹרָתֶךָ, וְאֵין לָמוֹ מִכְשׁוֹל: יְהִי שָׁלוֹם בְּחֵילֵךְ, שַׁלְוָה בְּאַרְמְנוֹתָיִךְ: לְמַעַן אַחַי וְרֵעָי אֲדַבְּרָה נָּא שָׁלוֹם בָּךְ: לְמַעַן בֵּית יהוה אֱלֹהֵינוּ אֲבַקְשָׁה טוֹב לָךְ: יהוה עֹז לְעַמּוֹ יִתֵּן, יהוה יְבָרֵךְ אֶת עַמּוֹ בַשָּׁלוֹם:","cond":["noTishaaBeav"]},{"kind":"instruction","text":"קדיש דרבנן","cond":["noTishaaBeav"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":["noTishaaBeav"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noTishaaBeav","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noTishaaBeav","ayt"]},{"kind":"text","text":"עַל יִשְׂרָאֵל וְעַל רַבָּנָן וְעַל תַּלְמִידֵיהוֹן וְעַל כָּל תַּלְמִידֵי תַלְמִידֵיהוֹן וְעַל כָּל מָאן דְּעָסְקִין בְּאוֹרַיְתָא דִּי בְאַתְרָא (קַדִּישָׁא) הָדֵין וְדִי בְכָל אָתָר וְאָתָר, יְהֵא לְהוֹן וּלְכוֹן שְׁלָמָא רַבָּא חִנָּא וְחִסְדָּא וְרַחֲמֵי וְחַיֵּי אֲרִיכֵי וּמְזוֹנֵי רְוִיחֵי וּפֻרְקָנָא מִן קֳדָם אֲבוּהוֹן דִּי בִשְׁמַיָּא וְאַרְעָא וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":["noTishaaBeav"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noTishaaBeav","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noTishaaBeav","ayt"]},{"kind":"instruction","text":"חזן:","cond":["noTora"]},{"kind":"text","text":"בָּרְכוּ אֶת יהוה הַמְבֹרָךְ.","cond":["noTora"]},{"kind":"instruction","text":"קהל וחזן:","cond":["noTora"]},{"kind":"text","text":"בָּרוּךְ יהוה הַמְבֹרָךְ לְעוֹלָם וָעֶד.","cond":["noTora"]},{"kind":"header","text":"עלינו לשבח","cond":[]},{"kind":"text","text":"עָלֵינוּ לְשַׁבֵּחַ לַאֲדוֹן הַכֹּל, לָתֵת גְּדֻלָּה לְיוֹצֵר בְּרֵאשִׁית, שֶׁלֹּא עָשָׂנוּ כְּגוֹיֵי הָאֲרָצוֹת, וְלֹא שָׂמָנוּ כְּמִשְׁפְּחוֹת הָאֲדָמָה. שֶׁלֹּא שָׂם חֶלְקֵנוּ כָּהֶם, וְגוֹרָלֵנוּ כְּכָל-הֲמוֹנָם[, שֶׁהֵם מִשְׁתַּחֲוִים לְהֶבֶל וָרִיק, וּמִתְפַּלְּלִים אֶל אֵל לֹא יוֹשִׁיעַ]. וַאֲנַחְנוּ כּוֹרְעִים וּמִשְׁתַּחֲוִים וּמוֹדִים לִפְנֵי מֶלֶךְ מַלְכֵי הַמְּלָכִים הַקָּדוֹשׁ בָּרוּךְ הוּא, שֶׁהוּא נוֹטֶה שָׁמַיִם וְיוֹסֵד אָרֶץ, וּמוֹשַׁב יְקָרוֹ בַּשָּׁמַיִם מִמַּעַל, וּשְׁכִינַת עֻזּוֹ בְּגָבְהֵי מְרוֹמִים. הוּא אֱלֹהֵינוּ, אֵין עוֹד, אֱמֶת מַלְכֵּנוּ, אֶפֶס זוּלָתוֹ. כַּכָּתוּב בְּתוֹרָתוֹ: וְיָדַעְתָּ הַיּוֹם וַהֲשֵׁבֹתָ אֶל לְבָבֶךָ כִּי יהוה הוּא הָאֱלֹהִים בַּשָּׁמַיִם מִמַּעַל וְעַל הָאָרֶץ מִתָּחַת אֵין עוֹד:","cond":[]},{"kind":"text","text":"וְעַל כֵּן נְקַוֶּה לְךָ יהוה אֱלֹהֵינוּ, לִרְאוֹת מְהֵרָה בְּתִפְאֶרֶת עֻזֶּךָ, לְהַעֲבִיר גִּלּוּלִים מִן הָאָרֶץ, וְהָאֱלִילִים כָּרוֹת יִכָּרֵתוּן, לְתַקֵּן עוֹלָם בְּמַלְכוּת שַׁדַּי, וְכָל בְּנֵי בָשָׂר יִקְרְאוּ בִשְׁמֶךָ, לְהַפְנוֹת אֵלֶיךָ כָּל רִשְׁעֵי אָרֶץ. יַכִּירוּ וְיֵדְעוּ כָּל יוֹשְׁבֵי תֵבֵל, כִּי לְךָ תִכְרַע כָּל בֶּרֶךְ, תִּשָּׁבַע כָּל לָשׁוֹן. לְפָנֶיךָ יהוה אֱלֹהֵינוּ יִכְרְעוּ וְיִפֹּלוּ, וְלִכְבוֹד שִׁמְךָ יְקָר יִתֵּנוּ, וִיקַבְּלוּ כֻלָּם אֶת עֹל מַלְכוּתֶךָ, וְתִמְלֹךְ עֲלֵיהֶם מְהֵרָה לְעוֹלָם וָעֶד. כִּי הַמַּלְכוּת שֶׁלְּךָ הִיא, וּלְעוֹלְמֵי עַד תִּמְלֹךְ בְּכָבוֹד. כַּכָּתוּב בְּתוֹרָתֶךָ: יהוה יִמְלֹךְ לְעֹלָם וָעֶד: וְנֶאֱמַר: וְהָיָה יהוה לְמֶלֶךְ עַל כָּל הָאָרֶץ, בַּיּוֹם הַהוּא יִהְיֶה יהוה אֶחָד וּשְׁמוֹ אֶחָד:","cond":[]},{"kind":"text","text":"אַל תִּירָא מִפַּחַד פִּתְאֹם וּמִשֹּׁאַת רְשָׁעִים כִּי תָבֹא: עֻצוּ עֵצָה וְתֻפָר, דַּבְּרוּ דָבָר וְלֹא יָקוּם, כִּי עִמָּנוּ אֵל: וְעַד זִקְנָה אֲנִי הוּא, וְעַד שֵׂיבָה אֲנִי אֶסְבֹּל אֲנִי עָשִׂיתִי וַאֲנִי אֶשָּׂא וַאֲנִי אֶסְבֹּל וַאֲמַלֵּט:","cond":[]},{"kind":"instruction","text":"קדיש יתום","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":[]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"header","text":"שש זכירות","cond":[]},{"kind":"instruction","text":"שש זכירות\n\nיציאת מצרים:","cond":[]},{"kind":"text","text":"לְמַעַן תִּזְכֹּר אֶת-יוֹם צֵאתְךָ מֵאֶרֶץ מִצְרַיִם כֹּל יְמֵי חַיֶּיךָ:","cond":[]},{"kind":"instruction","text":"מעמד הר סיני:","cond":[]},{"kind":"text","text":"רַק הִשָּׁמֶר לְךָ וּשְׁמֹר נַפְשְׁךָ מְאֹד פֶּן-תִּשְׁכַּח אֶת-הַדְּבָרִים אֲשֶׁר-רָאוּ עֵינֶיךָ וּפֶן-יָסוּרוּ מִלְּבָבְךָ כֹּל יְמֵי חַיֶּיךָ, וְהוֹדַעְתָּם לְבָנֶיךָ וְלִבְנֵי בָנֶיךָ: יוֹם אֲשֶׁר עָמַדְתָּ לִפְנֵי יהוה אֱלֹהֶיךָ בְּחֹרֵב, בֶּאֱמֹר יהוה אֵלַי הַקְהֶל-לִי אֶת-הָעָם וְאַשְׁמִעֵם אֶת-דְּבָרָי, אֲשֶׁר יִלְמְדוּן לְיִרְאָה אֹתִי כָּל-הַיָּמִים אֲשֶׁר הֵם חַיִּים עַל-הָאֲדָמָה וְאֶת-בְּנֵיהֶם יְלַמֵּדוּן:","cond":[]},{"kind":"instruction","text":"מעשה עמלק ומחייתו:","cond":[]},{"kind":"text","text":"זָכוֹר אֵת אֲשֶׁר-עָשָׂה לְךָ עֲמָלֵק, בַּדֶּרֶךְ בְּצֵאתְכֶם מִמִּצְרָיִם: אֲשֶׁר קָרְךָ בַּדֶּרֶךְ וַיְזַנֵּב בְּךָ כָּל-הַנֶּחֱשָׁלִים אַחַרֶיךָ וְאַתָּה עָיֵף וְיָגֵעַ, וְלֹא יָרֵא אֱלֹהִים: וְהָיָה בְּהָנִיחַ יהוה אֱלֹהֶיךָ לְךָ מִכָּל-אֹיְבֶיךָ מִסָּבִיב, בָּאָרֶץ אֲשֶׁר-יהוה אֱלֹהֶיךָ נֹתֵן לְךָ נַחֲלָה לְרִשְׁתָּהּ, תִּמְחֶה אֶת-זֵכֶר עֲמָלֵק מִתַּחַת הַשָּׁמָיִם, לֹא תִּשְׁכָּח:","cond":[]},{"kind":"instruction","text":"מעשי אבותינו במדבר:","cond":[]},{"kind":"text","text":"זְכֹר אַל תִּשְׁכַּח אֵת אֲשֶׁר-הִקְצַפְתָּ אֶת יהוה אֱלֹהֶיךָ בַּמִּדְבָּר, לְמִן-הַיּוֹם אֲשֶׁר-יָצָאתָ מֵאֶרֶץ מִצְרַיִם עַד-בֹּאֲכֶם עַד-הַמָּקוֹם הַזֶּה, מַמְרִים הֱיִיתֶם עִם-יהוה:","cond":[]},{"kind":"instruction","text":"מעשה מרים:","cond":[]},{"kind":"text","text":"זָכוֹר אֵת אֲשֶׁר-עָשָׂה יהוה אֱלֹהֶיךָ לְמִרְיָם, בַּדֶּרֶךְ בְּצֵאתְכֶם מִמִּצְרָיִם:","cond":[]},{"kind":"instruction","text":"שבת:","cond":[]},{"kind":"text","text":"זָכוֹר אֶת-יוֹם הַשַּׁבָּת לְקַדְּשׁוֹ:","cond":[]},{"kind":"header","text":"י\"ג עיקרים","cond":[]},{"kind":"instruction","text":"שלשה עשר עקרים","cond":[]},{"kind":"text","text":"א. אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה, שֶׁהַבּוֹרֵא יִתְבָּרַךְ שְׁמוֹ הוּא בּוֹרֵא וּמַנְהִיג לְכָל הַבְּרוּאִים, וְהוּא לְבַדּו עָשָׂה וְעוֹשֶׂה וְיַעֲשֶׂה לְכָל הַמַּעֲשִׂים.\nב. אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה, שֶׁהַבּוֹרֵא יִתְבָּרַךְ שְׁמוֹ הוּא יָחִיד וְאֵין יְחִידוּת כָּמוֹהוּ בְּשׁוּם פָּנִים, וְהוּא לְבַדּוֹ אֱלֹהֵינוּ, הָיָה הֹוֶה וְיִהְיֶה.\nג. אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה, שֶׁהַבּוֹרֵא יִתְבָּרַךְ שְׁמוֹ אֵינוֹ גוּף, וְלֹא יַשִּׂיגוּהוּ מַשִּׂיגֵי הַגּוּף, וְאֵין לוֹ שׁוּם דִּמְיוֹן כְּלָל.\nד. אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה, שֶׁהַבּוֹרֵא יִתְבָּרַךְ שְׁמוֹ הוּא רִאשׁוֹן וְהוּא אַחֲרוֹן.\nה. אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה, שֶׁהַבּוֹרֵא יִתְבָּרַךְ שְׁמוֹ לוֹ לְבַדּוֹ רָאוּי לְהִתְפַּלֵּל, וְאֵין רָאוּי לְהִתְפַּלֵּל לְזוּלָתוֹ.\nו. אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה, שֶׁכָּל דִּבְרֵי נְבִיאִים אֱמֶת.\nז. אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה, שֶׁנְּבוּאַת מֹשֶׁה רַבֵּנוּ עָלָיו הַשָּׁלוֹם הָיְתָה אֲמִתִּית, וְשֶׁהוּא הָיָה אָב לַנְּבִיאִים, לַקּוֹדְמִים לְפָנָיו וְלַבָּאִים אַחֲרָיו.\nח. אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה, שֶׁכָּל הַתּוֹרָה הַמְּצוּיָה עַתָּה בְיָדֵינוּ הִיא הַנְּתוּנָה לְמֹשֶׁה רַבֵּנוּ עָלָיו הַשָּׁלוֹם.\nט. אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה, שֶׁזֹּאת הַתּוֹרָה לֹא תְהֵא מֻחְלֶפֶת וְלֹא תְהֵא תוֹרָה אַחֶרֶת מֵאֵת הַבּוֹרֵא יִתְבָּרַךְ שְׁמוֹ.\nי. אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה, שֶׁהַבּוֹרֵא יִתְבָּרַךְ שְׁמוֹ יוֹדֵעַ כָּל מַעֲשֵׂה בְנֵי אָדָם וְכָל מַחְשְׁבוֹתָם, שֶׁנֶּאֱמַר: הַיֹּצֵר יַחַד לִבָּם, הַמֵּבִין אֶל כָּל מַעֲשֵׂיהֶם:\nיא. אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה, שֶׁהַבּוֹרֵא יִתְבָּרַךְ שְׁמוֹ גּוֹמֵל טוֹב לְשׁוֹמְרֵי מִצְוׂתָיו וּמַעֲנִישׁ לְעוֹבְרֵי מִצְוׂתָיו.\nיב. אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה, בְּבִיאַת הַמָּשִׁיחַ, וְאַף עַל פִּי שֶׁיִּתְמַהְמֵהַּ, עִם כָּל זֶה אֲחַכֶּה לּוֹ בְּכָל יוֹם שֶׁיָּבוֹא.\nיג. אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה, שֶׁתִּהְיֶה תְּחִיַּת הַמֵּתִים בְּעֵת שֶׁיַעֲלֶה רָצוֹן מֵאֵת הַבּוֹרֵא יִתְבָּרַךְ שְׁמוֹ וְיִתְעַלֶּה זִכְרוֹ לָעַד וּלְנֵצַח נְצָחִים.","cond":[]}],"mincha":[{"kind":"header","text":"הנחת תפילין","cond":["tishaaBeav"]},{"kind":"instruction","text":"מתעטפים בטלית ומניחים תפילין, ואומרים קריאת שמע. ויש אומרים שעדיף שלא לומר קריאת שמע מפני איסור לימוד תורה.","cond":["tishaaBeav"]},{"kind":"text","text":"שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:","cond":["tishaaBeav"]},{"kind":"instruction","text":"בלחש:","cond":["tishaaBeav"]},{"kind":"text","text":"בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד.\n\nוְאָהַבְתָּ אֵת יהוה אֱלֹהֶיךָ, בְּכָל לְבָבְךָ וּבְכָל נַפְשְׁךָ וּבְכָל מְאֹדֶךָ: וְהָיוּ הַדְּבָרִים הָאֵלֶּה אֲשֶׁר אָנֹכִי מְצַוְּךָ הַיּוֹם, עַל לְבָבֶךָ: וְשִׁנַּנְתָּם לְבָנֶיךָ וְדִבַּרְתָּ בָּם, בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ: וּקְשַׁרְתָּם לְאוֹת עַל יָדֶךָ, וְהָיוּ לְטֹטָפֹת בֵּין עֵינֶיךָ: וּכְתַבְתָּם עַל מְזֻזוֹת בֵּיתֶךָ וּבִשְׁעָרֶיךָ:","cond":["tishaaBeav"]},{"kind":"text","text":"וְהָיָה אִם שָׁמֹעַ תִּשְׁמְעוּ אֶל מִצְוׂתַי, אֲשֶׁר אָנֹכִי מְצַוֶּה אֶתְכֶם הַיּוֹם, לְאַהֲבָה אֶת יהוה אֱלֹהֵיכֶם וּלְעָבְדוֹ, בְּכָל לְבַבְכֶם וּבְכָל נַפְשְׁכֶם: וְנָתַתִּי מְטַר אַרְצְכֶם בְּעִתּוֹ, יוֹרֶה וּמַלְקוֹשׁ, וְאָסַפְתָּ דְגָנֶךָ וְתִירֹשְׁךָ וְיִצְהָרֶךָ: וְנָתַתִּי עֵשֶׂב בְּשָׂדְךָ לִבְהֶמְתֶּךָ, וְאָכַלְתָּ וְשָׂבָעְתָּ: הִשָּׁמְרוּ לָכֶם פֶּן יִפְתֶּה לְבַבְכֶם, וְסַרְתֶּם וַעֲבַדְתֶּם אֱלֹהִים אֲחֵרִים וְהִשְׁתַּחֲוִיתֶם לָהֶם: וְחָרָה אַף יהוה בָּכֶם, וְעָצַר אֶת הַשָּׁמַיִם וְלֹא יִהְיֶה מָטָר, וְהָאֲדָמָה לֹא תִתֵּן אֶת יְבוּלָהּ, וַאֲבַדְתֶּם מְהֵרָה מֵעַל הָאָרֶץ הַטֹּבָה אֲשֶׁר יהוה נֹתֵן לָכֶם: וְשַׂמְתֶּם אֶת דְּבָרַי אֵלֶּה עַל לְבַבְכֶם וְעַל נַפְשְׁכֶם, וּקְשַׁרְתֶּם אֹתָם לְאוֹת עַל יֶדְכֶם וְהָיוּ לְטוֹטָפֹת בֵּין עֵינֵיכֶם: וְלִמַּדְתֶּם אֹתָם אֶת בְּנֵיכֶם לְדַבֵּר בָּם, בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ: וּכְתַבְתָּם עַל מְזוּזוֹת בֵּיתֶךָ וּבִשְׁעָרֶיךָ: לְמַעַן יִרְבּוּ יְמֵיכֶם וִימֵי בְנֵיכֶם עַל הָאֲדָמָה אֲשֶׁר נִשְׁבַּע יהוה לַאֲבֹתֵיכֶם לָתֵת לָהֶם, כִּימֵי הַשָּׁמַיִם עַל הָאָרֶץ:","cond":["tishaaBeav"]},{"kind":"text","text":"וַיֹּאמֶר יהוה אֶל מֹשֶׁה לֵּאמֹר: דַּבֵּר אֶל בְּנֵי יִשְׂרָאֵל וְאָמַרְתָּ אֲלֵהֶם, וְעָשׂוּ לָהֶם צִיצִת עַל כַּנְפֵי בִגְדֵיהֶם לְדֹרֹתָם, וְנָתְנוּ עַל צִיצִת הַכָּנָף פְּתִיל תְּכֵלֶת: וְהָיָה לָכֶם לְצִיצִת, וּרְאִיתֶם אֹתוֹ, וּזְכַרְתֶּם אֶת כָּל מִצְוׂת יהוה וַעֲשִׂיתֶם אֹתָם, וְלֹא תָתֻרוּ אַחֲרֵי לְבַבְכֶם וְאַחֲרֵי עֵינֵיכֶם אֲשֶׁר אַתֶּם זֹנִים אַחֲרֵיהֶם: לְמַעַן תִּזְכְּרוּ וַעֲשִׂיתֶם אֶת כָּל מִצְוׂתָי, וִהְיִיתֶם קְדֹשִׁים לֵאלֹהֵיכֶם: אֲנִי יהוה אֱלֹהֵיכֶם אֲשֶׁר הוֹצֵאתִי אֶתְכֶם מֵאֶרֶץ מִצְרַיִם, לִהְיוֹת לָכֶם לֵאלֹהִים, אֲנִי יהוה אֱלֹהֵיכֶם:","cond":["tishaaBeav"]},{"kind":"text","text":"אֱמֶת.","cond":["tishaaBeav"]},{"kind":"text","text":"אַשְׁרֵי יוֹשְׁבֵי בֵיתֶךָ עוֹד יְהַלְלוּךָ סֶּלָה:\nאַשְׁרֵי הָעָם שֶׁכָּכָה לּוֹ אַשְׁרֵי הָעָם שֶׁיהוה אֱלֹהָיו:\nתְּהִלָּה לְדָוִד, אֲרוֹמִמְךָ אֱלוֹהַי הַמֶּלֶךְ וַאֲבָרְכָה שִׁמְךָ לְעוֹלָם וָעֶד:\nבְּכָל יוֹם אֲבָרְכֶךָּ וַאֲהַלְלָה שִׁמְךָ לְעוֹלָם וָעֶד:\nגָּדוֹל יהוה וּמְהֻלָּל מְאֹד וְלִגְדֻלָּתוֹ אֵין חֵקֶר:\nדּוֹר לְדוֹר יְשַׁבַּח מַעֲשֶׂיךָ וּגְבוּרֹתֶיךָ יַגִּידוּ:\nהֲדַר כְּבוֹד הוֹדֶךָ וְדִבְרֵי נִפְלְאוֹתֶיךָ אָשִׂיחָה:\nוֶעֱזוּז נוֹרְאֹתֶיךָ יֹאמֵרוּ וּגְדוּלָּתְךָ אֲסַפְּרֶנָּה:\nזֵכֶר רַב טוּבְךָ יַבִּיעוּ וְצִדְקָתְךָ יְרַנֵּנוּ:","cond":[]},{"kind":"text","text":"חַנּוּן וְרַחוּם יהוה אֶרֶךְ אַפַּיִם וּגְדָל חָסֶד:\nטוֹב יהוה לַכֹּל וְרַחֲמָיו עַל כָּל מַעֲשָׂיו:\nיוֹדוּךָ יהוה כָּל מַעֲשֶׂיךָ וַחֲסִידֶיךָ יְבָרְכוּכָה:\nכְּבוֹד מַלְכוּתְךָ יֹאמֵרוּ וּגְבוּרָתְךָ יְדַבֵּרוּ:\nלְהוֹדִיעַ לִבְנֵי הָאָדָם גְּבוּרֹתָיו וּכְבוֹד הֲדַר מַלְכוּתוֹ:\nמַלְכוּתְךָ מַלְכוּת כָּל עֹלָמִים וּמֶמְשַׁלְתְּךָ בְּכָל דּוֹר וָדוֹר:\nסוֹמֵךְ יהוה לְכָל הַנֹּפְלִים וְזוֹקֵף לְכָל הַכְּפוּפִים:\nעֵינֵי כֹל אֵלֶיךָ יְשַׂבֵּרוּ וְאַתָּה נוֹתֵן לָהֶם אֶת אָכְלָם בְּעִתּוֹ:","cond":[]},{"kind":"text","text":"פּוֹתֵחַ אֶת יָדֶךָ וּמַשְׂבִּיעַ לְכָל חַי רָצוֹן:\nצַדִּיק יהוה בְּכָל דְּרָכָיו וְחָסִיד בְּכָל מַעֲשָׂיו:\nקָרוֹב יהוה לְכָל קֹרְאָיו לְכֹל אֲשֶׁר יִקְרָאֻהוּ בֶאֱמֶת:\nרְצוֹן יְרֵאָיו יַעֲשֶׂה וְאֶת שַׁוְעָתָם יִשְׁמַע וְיוֹשִׁיעֵם:\nשׁוֹמֵר יהוה אֶת כָּל אֹהֲבָיו וְאֵת כָּל הָרְשָׁעִים יַשְׁמִיד:\nתְּהִלַּת יהוה יְדַבֶּר פִּי וִיבָרֵךְ כָּל בָּשָׂר שֵׁם קָדְשׁוֹ לְעוֹלָם וָעֶד:\nוַאֲנַחְנוּ נְבָרֵךְ יָהּ מֵעַתָּה וְעַד עוֹלָם הַלְלוּיָהּ:","cond":[]},{"kind":"instruction","text":"חצי קדיש","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":[]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"header","text":"הוצאת ספר תורה","cond":["taanit"]},{"kind":"instruction","text":"הוצאת ספר תורה","cond":["taanit"]},{"kind":"text","text":"וַיְהִי בִּנְסֹעַ הָאָרֹן, וַיֹּאמֶר מֹשֶׁה: קוּמָה יהוה וְיָפֻצוּ אֹיְבֶיךָ וְיָנֻסוּ מְשַׂנְאֶיךָ מִפָּנֶיךָ:\nכִּי מִצִּיּוֹן תֵּצֵא תוֹרָה, וּדְבַר יהוה מִירוּשָׁלָיִם:\nבָּרוּךְ שֶׁנָּתַן תּוֹרָה לְעַמּוֹ יִשְׂרָאֵל בִּקְדֻשָּׁתוֹ.\n\nבְּרִיךְ שְׁמֵהּ דְּמָרֵא עָלְמָא, בְּרִיךְ כִּתְרָךְ וְאַתְרָךְ. יְהֵא רְעוּתָךְ עִם עַמָּךְ יִשְׂרָאֵל לְעָלַם, וּפֻרְקַן יְמִינָךְ אַחֲזֵי לְעַמָּךְ בְּבֵית מַקְדְּשָׁךְ, וּלְאַמְטוֹיֵי לָנָא מִטּוּב נְהוֹרָךְ וּלְקַבֵּל צְלוֹתָנָא בְּרַחֲמִין. יְהֵא רַעֲוָא קֳדָמָךְ דְּתוֹרִיךְ לָן חַיִּין בְּטִיבוּ, וְלֶהֱוֵי אֲנָא פְקִידָא בְּגוֹ צַדִּיקַיָּא, לְמִרְחַם עָלַי וּלְמִנְטַר יָתִי וְיַת כָּל דִּי לִי וְדִי לְעַמָּךְ יִשְׂרָאֵל. אַנְתְּ הוּא זָן לְכֹלָּא וּמְפַרְנֵס לְכֹלָּא, אַנְתְּ הוּא שַׁלִּיט עַל כֹּלָּא, אַנְתְּ הוּא דְשַׁלִּיט עַל מַלְכַיָּא, וּמַלְכוּתָא דִּילָךְ הִיא. אֲנָא עַבְדָּא דְקֻדְשָׁא בְּרִיךְ הוּא, דְּסָגֵדְנָא קַמֵּהּ וּמִקַּמֵּי דִּיקַר אוֹרַיְתֵהּ בְּכָל עִדָּן וְעִדָּן. לָא עַל אֱנָשׁ רָחִיצְנָא וְלָא עַל בַּר אֱלָהִין סָמִיכְנָא, אֶלָּא בֵּאלָהָא דִשְׁמַיָּא, דְּהוּא אֱלָהָא קְשׁוֹט, וְאוֹרַיְתֵהּ קְשׁוֹט, וּנְבִיאוֹהִי קְשׁוֹט, וּמַסְגֵּא לְמֶעְבַּד טַבְוָן וּקְשׁוֹט. בֵּהּ אֲנָא רָחִיץ, וְלִשְׁמֵהּ קַדִּישָׁא יַקִּירָא אֲנָא אֵמַר תֻּשְׁבְּחָן. יְהֵא רַעֲוָא קֳדָמָךְ דְּתִפְתַּח לִבָּאִי בְּאוֹרַיְתָא, וְתַשְׁלִים מִשְׁאֲלִין דְּלִבַּאי וְלִבָּא דְכָל עַמָּךְ יִשְׂרָאֵל לְטַב וּלְחַיִּין וְלִשְׁלָם.\n\nחזן - גַּדְּלוּ לַיהוה אִתִּי וּנְרוֹמְמָה שְׁמוֹ יַחְדָּו:\nקהל - לְךָ יהוה הַגְּדֻלָּה וְהַגְּבוּרָה וְהַתִּפְאֶרֶת וְהַנֵּצַח וְהַהוֹד, כִּי כֹל בַּשָּׁמַיִם וּבָאָרֶץ, לְךָ יהוה הַמַּמְלָכָה וְהַמִּתְנַשֵּׂא לְכֹל לְרֹאשׁ: רוֹמְמוּ יהוה אֱלֹהֵינוּ וְהִשְׁתַּחֲווּ לַהֲדֹם רַגְלָיו, קָדוֹשׁ הוּא: רוֹמְמוּ יהוה אֱלֹהֵינוּ וְהִשְׁתַּחֲווּ לְהַר קָדְשׁוֹ, כִּי קָדוֹשׁ יהוה אֱלֹהֵינוּ:\n\nאַב הָרַחֲמִים הוּא יְרַחֵם עַם עֲמוּסִים, וְיִזְכֹּר בְּרִית אֵיתָנִים, וְיַצִּיל נַפְשׁוֹתֵינוּ מִן הַשָּׁעוֹת הָרָעוֹת, וְיִגְעַר בְּיֵצֶר הָרָע מִן הַנְּשׂוּאִים, וְיָחֹן אוֹתָנוּ לִפְלֵטַת עוֹלָמִים, וִימַלֵּא מִשְׁאֲלוֹתֵינוּ בְּמִדָּה טוֹבָה יְשׁוּעָה וְרַחֲמִים.","cond":["taanit"]},{"kind":"instruction","text":"קריאת התורה","cond":["taanit"]},{"kind":"instruction","text":"לפני הקריאה מברך העולה:","cond":["taanit"]},{"kind":"instruction","text":"חזן:","cond":["taanit"]},{"kind":"text","text":"בָּרְכוּ אֶת יהוה הַמְבֹרָךְ.","cond":["taanit"]},{"kind":"instruction","text":"קהל וחזן:","cond":["taanit"]},{"kind":"text","text":"בָּרוּךְ יהוה הַמְבֹרָךְ לְעוֹלָם וָעֶד.","cond":["taanit"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר בָּחַר בָּנוּ מִכָּל הָעַמִּים וְנָתַן לָנוּ אֶת תּוֹרָתוֹ. בָּרוּךְ אַתָּה יהוה, נוֹתֵן הַתּוֹרָה.","cond":["taanit"]},{"kind":"instruction","text":"לאחר הקריאה מברך העולה:","cond":["taanit"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר נָתַן לָנוּ תּוֹרַת אֱמֶת וְחַיֵּי עוֹלָם נָטַע בְּתוֹכֵנוּ. בָּרוּךְ אַתָּה יהוה, נוֹתֵן הַתּוֹרָה.","cond":["taanit"]},{"kind":"header","text":"קריאת התורה","cond":["taanit"]},{"kind":"text","text":"וַיְחַל מֹשֶׁה אֶת פְּנֵי יהוה אֱלֹהָיו, וַיֹּאמֶר לָמָה יהוה יֶחֱרֶה אַפְּךָ בְּעַמֶּךָ אֲשֶׁר הוֹצֵאתָ מֵאֶרֶץ מִצְרַיִם בְּכֹחַ גָּדוֹל וּבְיָד חֲזָקָה: לָמָּה יֹאמְרוּ מִצְרַיִם לֵאמֹר בְּרָעָה הוֹצִיאָם לַהֲרֹג אֹתָם בֶּהָרִים וּלְכַלֹּתָם מֵעַל פְּנֵי הָאֲדָמָה, שׁוּב מֵחֲרוֹן אַפֶּךָ וְהִנָּחֵם עַל הָרָעָה לְעַמֶּךָ: זְכֹר לְאַבְרָהָם לְיִצְחָק וּלְיִשְׂרָאֵל עֲבָדֶיךָ אֲשֶׁר נִשְׁבַּעְתָּ לָהֶם בָּךְ, וַתְּדַבֵּר אֲלֵהֶם אַרְבֶּה אֶת זַרְעֲכֶם כְּכוֹכְבֵי הַשָּׁמָיִם, וְכָל הָאָרֶץ הַזֹּאת אֲשֶׁר אָמַרְתִּי אֶתֵּן לְזַרְעֲכֶם וְנָחֲלוּ לְעֹלָם: וַיִּנָּחֶם יהוה, עַל הָרָעָה אֲשֶׁר דִּבֶּר לַעֲשׂוֹת לְעַמּוֹ:","cond":["taanit"]},{"kind":"instruction","text":"עד כאן לכהן","cond":["taanit"]},{"kind":"text","text":"וַיֹּאמֶר יהוה אֶל מֹשֶׁה פְּסָל לְךָ שְׁנֵי לֻחֹת אֲבָנִים כָּרִאשֹׁנִים, וְכָתַבְתִּי עַל הַלֻּחֹת אֶת הַדְּבָרִים אֲשֶׁר הָיוּ עַל הַלֻּחֹת הָרִאשֹׁנִים אֲשֶׁר שִׁבַּרְתָּ: וֶהְיֵה נָכוֹן לַבֹּקֶר, וְעָלִיתָ בַבֹּקֶר אֶל הַר סִינַי וְנִצַּבְתָּ לִי שָׁם עַל רֹאשׁ הָהָר: וְאִישׁ לֹא יַעֲלֶה עִמָּךְ וְגַם אִישׁ אַל יֵרָא בְּכָל הָהָר, גַּם הַצֹּאן וְהַבָּקָר אַל יִרְעוּ אֶל מוּל הָהָר הַהוּא:","cond":["taanit"]},{"kind":"instruction","text":"עד כאן ללוי","cond":["taanit"]},{"kind":"text","text":"וַיִּפְסֹל שְׁנֵי לֻחֹת אֲבָנִים כָּרִאשֹׁנִים, וַיַּשְׁכֵּם מֹשֶׁה בַבֹּקֶר וַיַּעַל אֶל הַר סִינַי כַּאֲשֶׁר צִוָּה יהוה אֹתוֹ, וַיִּקַּח בְּיָדוֹ שְׁנֵי לֻחֹת אֲבָנִים: וַיֵּרֶד יהוה בֶּעָנָן וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם, יהוה: וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא, יהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה לֹא יְנַקֶּה, פֹּקֵד עֲוׂן אָבוֹת עַל בָּנִים וְעַל בְּנֵי בָנִים, עַל שִׁלֵּשִׁים וְעַל רִבֵּעִים: וַיְמַהֵר מֹשֶׁה, וַיִּקֹּד אַרְצָה וַיִּשְׁתָּחוּ: וַיֹּאמֶר אִם נָא מָצָאתִי חֵן בְּעֵינֶיךָ אֲדֹנָי יֵלֶךְ נָא אֲדֹנָי בְּקִרְבֵּנוּ, כִּי עַם קְשֵׁה עֹרֶף הוּא, וְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ: וַיֹּאמֶר הִנֵּה אָנֹכִי כֹּרֵת בְּרִית, נֶגֶד כָּל עַמְּךָ אֶעֱשֶׂה נִפְלָאֹת אֲשֶׁר לֹא נִבְרְאוּ בְכָל הָאָרֶץ וּבְכָל הַגּוֹיִם, וְרָאָה כָל הָעָם אֲשֶׁר אַתָּה בְקִרְבּוֹ אֶת מַעֲשֵׂה יהוה כִּי נוֹרָא הוּא, אֲשֶׁר אֲנִי עֹשֶׂה עִמָּךְ:","cond":["taanit"]},{"kind":"instruction","text":"עד כאן לישראל","cond":["taanit"]},{"kind":"instruction","text":"הגבהה וגלילה","cond":["taanit"]},{"kind":"text","text":"וְזֹאת הַתּוֹרָה אֲשֶׁר שָׂם מֹשֶׁה לִפְנֵי בְּנֵי יִשְׂרָאֵל עַל פִּי יהוה בְּיַד מֹשֶׁה.","cond":["taanit"]},{"kind":"header","text":"הפטרה","cond":["taanit"]},{"kind":"instruction","text":"הפטרה","cond":["taanit"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר בָּחַר בִּנְבִיאִים טוֹבִים, וְרָצָה בְדִבְרֵיהֶם הַנֶּאֱמָרִים בֶּאֱמֶת. בָּרוּךְ אַתָּה יהוה, הַבּוֹחֵר בַּתּוֹרָה וּבְמֹשֶׁה עַבְדּוֹ, וּבְיִשְׂרָאֵל עַמּוֹ, וּבִנְבִיאֵי הָאֱמֶת וְהַצֶּדֶק.","cond":["taanit"]},{"kind":"text","text":"דִּרְשׁוּ יהוה בְּהִמָּצְאוֹ, קְרָאֻהוּ בִּהְיוֹתוֹ קָרוֹב: יַעֲזֹב רָשָׁע דַּרְכּוֹ וְאִישׁ אָוֶן מַחְשְׁבֹתָיו, וְיָשֹׁב אֶל יהוה וִירַחֲמֵהוּ, וְאֶל אֱלֹהֵינוּ כִּי יַרְבֶּה לִסְלוֹחַ: כִּי לֹא מַחְשְׁבוֹתַי מַחְשְׁבוֹתֵיכֶם, וְלֹא דַרְכֵיכֶם דְּרָכָי, נְאֻם יהוה: כִּי גָבְהוּ שָׁמַיִם מֵאָרֶץ, כֵּן גָּבְהוּ דְרָכַי מִדַּרְכֵיכֶם וּמַחְשְׁבֹתַי מִמַּחְשְׁבֹתֵיכֶם: כִּי כַּאֲשֶׁר יֵרֵד הַגֶּשֶׁם וְהַשֶּׁלֶג מִן הַשָּׁמַיִם, וְשָׁמָּה לֹא יָשׁוּב, כִּי אִם הִרְוָה אֶת הָאָרֶץ וְהוֹלִידָהּ וְהִצְמִיחָהּ, וְנָתַן זֶרַע לַזֹּרֵעַ וְלֶחֶם לָאֹכֵל: כֵּן יִהְיֶה דְבָרִי אֲשֶׁר יֵצֵא מִפִּי, לֹא יָשׁוּב אֵלַי רֵיקָם, כִּי אִם עָשָׂה אֶת אֲשֶׁר חָפַצְתִּי וְהִצְלִיחַ אֲשֶׁר שְׁלַחְתִּיו: כִּי בְשִׂמְחָה תֵצֵאוּ וּבְשָׁלוֹם תּוּבָלוּן, הֶהָרִים וְהַגְּבָעוֹת יִפְצְחוּ לִפְנֵיכֶם רִנָּה וְכָל עֲצֵי הַשָּׂדֶה יִמְחֲאוּ כָף: תַּחַת הַנַּעֲצוּץ יַעֲלֶה בְרוֹשׁ, וְתַחַת הַסִּרְפַּד יַעֲלֶה הֲדַס, וְהָיָה לַיהוה לְשֵׁם, לְאוֹת עוֹלָם לֹא יִכָּרֵת: כֹּה אָמַר יהוה, שִׁמְרוּ מִשְׁפָּט וַעֲשׂוּ צְדָקָה, כִּי קְרוֹבָה יְשׁוּעָתִי לָבוֹא וְצִדְקָתִי לְהִגָּלוֹת: אַשְׁרֵי אֱנוֹשׁ יַעֲשֶׂה זֹּאת וּבֶן אָדָם יַחֲזִיק בָּהּ, שֹׁמֵר שַׁבָּת מֵחַלְּלוֹ וְשֹׁמֵר יָדוֹ מֵעֲשׂוֹת כָּל רָע: וְאַל יֹאמַר בֶּן הַנֵּכָר הַנִּלְוָה אֶל יהוה לֵאמֹר הַבְדֵּל יַבְדִּילַנִי יהוה מֵעַל עַמּוֹ, וְאַל יֹאמַר הַסָּרִיס הֵן אֲנִי עֵץ יָבֵשׁ: כִּי כֹה אָמַר יהוה לַסָּרִיסִים אֲשֶׁר יִשְׁמְרוּ אֶת שַׁבְּתוֹתַי וּבָחֲרוּ בַּאֲשֶׁר חָפָצְתִּי וּמַחֲזִיקִים בִּבְרִיתִי: וְנָתַתִּי לָהֶם בְּבֵיתִי וּבְחוֹמֹתַי יָד וָשֵׁם, טוֹב מִבָּנִים וּמִבָּנוֹת, שֵׁם עוֹלָם אֶתֶּן לוֹ אֲשֶׁר לֹא יִכָּרֵת: וּבְנֵי הַנֵּכָר הַנִּלְוִים עַל יהוה לְשָׁרְתוֹ וּלְאַהֲבָה אֶת שֵׁם יהוה לִהְיוֹת לוֹ לַעֲבָדִים, כָּל שֹׁמֵר שַׁבָּת מֵחַלְּלוֹ וּמַחֲזִיקִים בִּבְרִיתִי: וַהֲבִיאוֹתִים אֶל הַר קָדְשִׁי וְשִׂמַּחְתִּים בְּבֵית תְּפִלָּתִי, עוֹלֹתֵיהֶם וְזִבְחֵיהֶם לְרָצוֹן עַל מִזְבְּחִי, כִּי בֵיתִי בֵּית תְּפִלָּה יִקָּרֵא לְכָל הָעַמִּים: נְאֻם אֲדֹנָי יֱהֹוִה מְקַבֵּץ נִדְחֵי יִשְׂרָאֵל, עוֹד אֲקַבֵּץ עָלָיו לְנִקְבָּצָיו:","cond":["taanit"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, צוּר כָּל הָעוֹלָמִים, צַדִּיק בְּכָל הַדּוֹרוֹת, הָאֵל הַנֶּאֱמָן הָאוֹמֵר וְעוֹשֶׂה, הַמְדַבֵּר וּמְקַיֵּם שֶׁכָּל דְּבָרָיו אֱמֶת וָצֶדֶק. נֶאֱמָן אַתָּה הוּא יהוה אֱלֹהֵינוּ וְנֶאֱמָנִים דְּבָרֶיךָ, וְדָבָר אֶחָד מִדְּבָרֶיךָ אָחוֹר לֹא יָשׁוּב רֵיקָם, כִּי אֵל מֶלֶךְ נֶאֱמָן וְרַחֲמָן אָתָּה. בָּרוּךְ אַתָּה יהוה, הָאֵל הַנֶּאֱמָן בְּכָל דְּבָרָיו.\n\nרַחֵם עַל צִיּוֹן כִּי הִיא בֵּית חַיֵּינוּ, וְלַעֲלוּבַת נֶפֶשׁ תּוֹשִׁיעַ בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יהוה, מְשמֵּחַ צִיּוֹן בְּבָנֶיהָ.\n\nשַׂמְּחֵנוּ יהוה אֱלֹהֵינוּ בְּאֵלִיָּהוּ הַנָּבִיא עַבְדֶּךָ, וּבְמַלְכוּת בֵּית דָּוִד מְשִׁיחֶךָ, בִּמְהֵרָה יָבוֹא וְיָגֵל לִבֵּנוּ, עַל כִּסְאוֹ לֹא יֵשֵׁב זָר וְלֹא יִנְחֲלוּ עוֹד אֲחֵרִים אֶת כְּבוֹדוֹ, כִּי בְשֵׁם קָדְשְׁךָ נִשְׁבַּעְתָּ לּוֹ שֶׁלֹּא יִכְבֶּה נֵרוֹ לְעוֹלָם וָעֶד. בָּרוּךְ אַתָּה יהוה, מָגֵן דָּוִד.","cond":["taanit"]},{"kind":"header","text":"הכנסת ספר תורה","cond":["taanit"]},{"kind":"instruction","text":"הכנסת ספר תורה","cond":["taanit"]},{"kind":"text","text":"יְהַלְלוּ אֶת שֵׁם יהוה, כִּי נִשְׂגָּב שְׁמוֹ לְבַדּוֹ.\nוהקהל אומרים - הוֹדוֹ עַל אֶרֶץ וְשָׁמָיִם: וַיָּרֶם קֶרֶן לְעַמּוֹ, תְּהִלָּה לְכָל חֲסִידָיו, לִבְנֵי יִשְׂרָאֵל עַם קְרוֹבוֹ, הַלְלוּיָהּ:\n\nלְדָוִד מִזְמוֹר, לַיהוה הָאָרֶץ וּמְלוֹאָהּ, תֵּבֵל וְיֹשְׁבֵי בָהּ: כִּי הוּא עַל יַמִּים יְסָדָהּ, וְעַל נְהָרוֹת יְכוֹנְנֶהָ: מִי יַעֲלֶה בְהַר יהוה, וּמִי יָקוּם בִּמְקוֹם קָדְשׁוֹ: נְקִי כַפַּיִם וּבַר לֵבָב, אֲשֶׁר לֹא נָשָׂא לַשָּׁוְא נַפְשִׁי וְלֹא נִשְׁבַּע לְמִרְמָה: יִשָּׂא בְרָכָה מֵאֵת יהוה, וּצְדָקָה מֵאֱלֹהֵי יִשְׁעוֹ: זֶה דּוֹר דֹּרְשָׁיו, מְבַקְשֵׁי פָנֶיךָ יַעֲקֹב סֶלָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וְהִנָּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבוֹא מֶלֶךְ הַכָּבוֹד: מִי זֶה מֶלֶךְ הַכָּבוֹד, יהוה עִזּוּז וְגִבּוֹר, יהוה גִּבּוֹר מִלְחָמָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבֹא מֶלֶךְ הַכָּבוֹד: מִי הוּא זֶה מֶלֶךְ הַכָּבוֹד, יהוה צְבָאוֹת הוּא מֶלֶךְ הַכָּבוֹד סֶלָה:","cond":["taanit"]},{"kind":"instruction","text":"כשמכניסים את הספר אומרים","cond":["taanit"]},{"kind":"text","text":"וּבְנֻחֹה יֹאמַר: שׁוּבָה יהוה רִבְבוֹת אַלְפֵי יִשְׂרָאֵל: קוּמָה יהוה לִמְנוּחָתֶךָ, אַתָּה וַאֲרוֹן עֻזֶּךָ: כֹּהֲנֶיךָ יִלְבְּשׁוּ צֶדֶק, וַחֲסִידֶיךָ יְרַנֵּנוּ: בַּעֲבוּר דָּוִד עַבְדֶּךָ אַל תָּשֵׁב פְּנֵי מְשִׁיחֶךָ: כִּי לֶקַח טוֹב נָתַתִּי לָכֶם, תּוֹרָתִי אַל תַּעֲזֹבוּ: עֵץ חַיִּים הִיא לַמַּחֲזִיקִים בָּהּ, וְתֹמְכֶיהָ מְאֻשָּׁר: דְּרָכֶיהָ דַרְכֵי נֹעַם וְכָל נְתִיבוֹתֶיהָ שָׁלוֹם: הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם:","cond":["taanit"]},{"kind":"instruction","text":"חצי קדיש","cond":["taanit"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":["taanit"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["taanit","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["taanit","ayt"]},{"kind":"header","text":"עמידה","cond":[]},{"kind":"instruction","text":"תפילת העמידה","cond":[]},{"kind":"text","text":"כִּי שֵׁם יהוה אֶקְרָא, הָבוּ גֹדֶל לֵאלֹהֵינוּ:\nאֲדֹנָי, שְׂפָתַי תִּפְתָּח, וּפִי יַגִּיד תְּהִלָּתֶךָ:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק, וֵאלֹהֵי יַעֲקֹב, הָאֵל הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, וְקוֹנֵה הַכֹּל, וְזוֹכֵר חַסְדֵי אָבוֹת, וּמֵבִיא גוֹאֵל לִבְנֵי בְנֵיהֶם לְמַעַן שְׁמוֹ בְּאַהֲבָה.","cond":[]},{"kind":"special","text":"זָכְרֵנוּ לְחַיִּים, מֶלֶךְ חָפֵץ בַּחַיִּים, וְכָתְבֵנוּ בְּסֵפֶר הַחַיִּים, לְמַעַנְךָ אֱלֹהִים חַיִּים.","cond":["ayt"]},{"kind":"text","text":"מֶלֶךְ עוֹזֵר וּמוֹשִׁיעַ וּמָגֵן. בָּרוּךְ אַתָּה יהוה, מָגֵן אַבְרָהָם.","cond":[]},{"kind":"text","text":"אַתָּה גִּבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֵּה מֵתִים אַתָּה רַב לְהוֹשִׁיעַ,","cond":[]},{"kind":"summer","text":"מוֹרִיד הַטָּל,","cond":["summerTal"]},{"kind":"winter","text":"מַשִּׁיב הָרוּחַ וּמוֹרִיד הַגֶּשֶׁם,","cond":["winterTal"]},{"kind":"text","text":"מְכַלְכֵּל חַיִּים בְּחֶסֶד, מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים, סוֹמֵךְ נוֹפְלִים, וְרוֹפֵא חוֹלִים וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמוּנָתוֹ לִישֵׁנֵי עָפָר. מִי כָמוֹךָ בַּעַל גְּבוּרוֹת וּמִי דּוֹמֶה לָךְ, מֶלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִיחַ יְשׁוּעָה.","cond":[]},{"kind":"special","text":"מִי כָמוֹךָ אַב הָרַחֲמָן, זוֹכֵר יְצוּרָיו לְחַיִּים בְּרַחֲמִים.","cond":["ayt"]},{"kind":"text","text":"וְנֶאֱמָן אַתָּה לְהַחֲיוֹת מֵתִים. בָּרוּךְ אַתָּה יהוה, מְחַיֵּה הַמֵּתִים.","cond":[]},{"kind":"text","text":"אַתָּה קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ וּקְדוֹשִׁים בְּכָל יוֹם יְהַלְלוּךָ סֶּלָה, כִּי אֵל מֶלֶךְ גָּדוֹל וְקָדוֹשׁ אָתָּה.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הָאֵל הַקָּדוֹשׁ.","cond":["noayt"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יהוה, הַמֶּלֶךְ הַקָּדוֹשׁ.","cond":["ayt"]},{"kind":"text","text":"אַתָּה חוֹנֵן לְאָדָם דַּעַת וּמְלַמֵּד לֶאֱנוֹשׁ בִּינָה.","cond":[]},{"kind":"text","text":"חָנֵּנוּ מִאִתְּךָ חָכְמָה בִּינָה וָדָעַת","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, חוֹנֵן הַדָּעַת.","cond":[]},{"kind":"text","text":"הֲשִׁיבֵנוּ אָבִינוּ לְתוֹרָתֶךָ, וְקָרְבֵנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶך, וְהַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ. בָּרוּךְ אַתָּה יהוה, הָרוֹצֶה בִּתְשׁוּבָה.","cond":[]},{"kind":"text","text":"סְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ, כִּי אֵל טוֹב וְסַלָּח אָתָּה. בָּרוּךְ אַתָּה יהוה, חַנּוּן הַמַּרְבֶּה לִסְלֹחַ.","cond":[]},{"kind":"text","text":"רְאֵה נָא בְעָנְיֵנוּ, וְרִיבָה רִיבֵנוּ, וּגְאָלֵנוּ גְאֻלָּה שְׁלֵמָה מְהֵרָה לְמַעַן שְׁמֶךָ, כִּי אֵל גּוֹאֵל חָזָק אָתָּה. בָּרוּךְ אַתָּה יהוה, גּוֹאֵל יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"רְפָאֵנוּ יהוה וְנֵרָפֵא, הוֹשִׁיעֵנוּ וְנִוָּשֵׁעָה כִּי תְהִלָּתֵנוּ אָתָּה, וְהַעֲלֵה (אֲרוּכָה וּמַרְפֵּא לְכָל תַּחֲלוּאֵינוּ וּלְכָל מַכְאוֹבֵינוּ) רְפוּאָה שְׁלֵמָה לְכָל מַכּוֹתֵינוּ.","cond":[]},{"kind":"special","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁתִּשְׁלַח מְהֵרָה רְפוּאָה שְׁלֵמָה מִן הַשָּׁמַיִם, רְפוּאַת הַנֶּפֶשׁ וּרְפוּאַת הַגּוּף לַחוֹלֶה (לנקבה: לַחוֹלָה, לרבים: לַחוֹלִים, לרבות: לַחוֹלוֹת):\n:=:=\nבְּתוֹךְ שְׁאָר חוֹלֵי יִשְׂרָאֵל.","cond":["doctor"]},{"kind":"text","text":"כִּי אֵל מֶלֶךְ רוֹפֵא נֶאֱמָן וְרַחֲמָן אָתָּה. בָּרוּךְ אַתָּה יהוה, רוֹפֵא חוֹלֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"בָּרֵך עָלֵינוּ יהוה אֱלֹהֵינוּ אֶת הַשָּׁנָה הַזֹּאת וְאֶת כָּל מִינֵי תְבוּאָתָהּ לְטוֹבָה, וְתֵן","cond":[]},{"kind":"summer","text":"בְּרָכָה","cond":["summerBracha"]},{"kind":"winter","text":"טַל וּמָטָר לִבְרָכָה","cond":["winterBracha"]},{"kind":"text","text":"עַל פְּנֵי הָאֲדָמָה וְשַׂבְּעֵנוּ מִטּוּבָהּ, וּבָרֵךְ שְׁנָתֵנוּ כַּשָּׁנִים הַטּוֹבוֹת לִבְרָכָה. כִּי אֵל טוֹב וּמֵטִיב אַתָּה וּמְבָרֵךְ הַשָּׁנִים. בָּרוּךְ אַתָּה יהוה, מְבָרֵךְ הַשָּׁנִים.","cond":[]},{"kind":"text","text":"תְּקַע בְּשׁוֹפָר גָּדוֹל לְחֵרוּתֵנוּ וְשָׂא נֵס לְקַבֵּץ גָּלֻיּוֹתֵינוּ, וְקַבְּצֵנוּ יַחַד מְהֵרָה מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ לְאַרְצֵנוּ. בָּרוּךְ אַתָּה יהוה, מְקַבֵּץ נִדְחֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"הָשִׁיבָה שׁוֹפְטֵינוּ כְּבָרִאשׁוֹנָה וְיוֹעֲצֵינוּ כְּבַתְּחִלָּה, וְהָסֵר מִמֶּנּוּ יָגוֹן וַאֲנָחָה, וּמְלֹךְ עָלֵינוּ מְהֵרָה אַתָּה יהוה לְבַדְּךָ בְּחֶסֶד וּבְרַחֲמִים, בְּצֶדֶק וּבְמִשְׁפָט.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, מֶלֶךְ אוֹהֵב צְדָקָה וּמִשְׁפָּט.","cond":["noayt"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יהוה, הַמֶּלֶךְ הַמִּשְׁפָּט.","cond":["ayt"]},{"kind":"text","text":"וְלַמַּלְשִׁינִים אַל תְּהִי תִקְוָה, וְכָל הַמִּינִים כְּרֶגַע יֹאבֵדוּ. וְכָל אוֹיְבֵי עַמְּךָ מְהֵרָה יִכָּרֵתוּ, וְהַזֵּדִים מְהֵרָה תְעַקֵּר וּתְשַׁבֵּר וּתְמַגֵּר וּתְכַלֵּם וְתַשְׁפִּילֵם וְתַכְנִיעֵם בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יהוה, שׁוֹבֵר אוֹיְבִים וּמַכְנִיעַ זֵדִים.","cond":[]},{"kind":"text","text":"עַל הַצַּדִּיקִים וְעַל הַחֲסִידִים, וְעַל זִקְנֵי שְׁאֵרִית עַמְּךָ בֵּית יִשְׂרָאֵל, וְעַל פְּלֵיטַת בֵּית סוֹפרֵיהֶם, וְעַל גֵּרֵי הַצֶדֶק וְעָלֵינוּ, יֶהֱמוּ נָא רַחֲמֶיךָ יהוה אֱלֹהֵינוּ, וְתֵן שָׂכָר טוֹב לְכָל הַבּוֹטְחִים בְּשִׁמְךָ בֶּאֱמֶת, וְשִׂים חֶלְקֵנוּ עִמָּהֶם וּלְעוֹלָם לֹא נֵבוֹשׁ כִּי בְךָ בָטָחְנוּ וְעַל חַסְדְּךָ הַגָּדוֹל בֶּאֱמֶת (וּבְתָמִים) נִשְׁעַנּוּ. בָּרוּךְ אַתָּה יהוה, מִשְׁעָן וּמִבְטָח לַצַּדִּיקִים.","cond":[]},{"kind":"text","text":"וְלִירוּשָׁלַיִם עִירְךָ בְּרַחֲמִים תָּשׁוּב וְתִשְׁכֹּן בְּתוֹכָהּ כַּאֲשֶׁר דִּבַּרְתָּ, וּבְנֵה אוֹתָהּ בְּקָרוֹב בְּיָמֵינוּ בִּנְיָן עוֹלָם, וְכִסֵּא דָוִד עַבְדְּךָ מְהֵרָה לְתוֹכָהּ תָּכִין.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, בּוֹנֵה יְרוּשָׁלָיִם.","cond":["noTishaaBeav"]},{"kind":"special","text":"נַחֵם יהוה אֱלֹהֵינוּ אֶת אֲבֵלֵי צִיּוֹן וְאֶת אֲבֵלֵי יְרוּשָלַיִם וְאֶת הָעִיר הָאֲבֵלָה וְהַחֲרֵבָה וְהַבְּזוּיָה וְהַשּׁוֹמְמָה. הָאֲבֵלָה מִבְּלִי בָנֶיהָ וְהַחֲרֵבָה מִמְּעוֹנוֹתֶיהָ, וְהַבְּזוּיָה מִכְּבוֹדָהּ, וְהַשּׁוֹמְמָה מֵאֵין יוֹשֵׁב. וְהִיא יוֹשֶׁבֶת וְראשָׁהּ חָפוּי כְּאִשָּׁה עֲקָרָה שֶׁלֹּא יָלָדָה. וַיְבַלְּעוּהָ לִגְיוֹנוֹת, וַיִּירָשׁוּהָ עוֹבְדֵי זָרִים, וַיָּטִילוּ אֶת עַמְּךָ יִשְׂרָאֵל לֶחָרֶב, וַיַּהַרְגוּ בְזָדוֹן חֲסִידֵי עֶלְיוֹן. עַל כֵּן צִיּוֹן בְּמַר תִּבְכֶּה, וִירוּשָׁלַיִם תִּתֵּן קוֹלָהּ. לִבִּי לִבִּי עַל חַלְלֵיהֶם, מֵעַי מֵעַי עַל חַלְלֵיהֶם, כִּי אַתָּה יהוה בָּאֵשׁ הִצַּתָּהּ, וּבָאֵשׁ אַתָּה עָתִיד לִבְנוֹתָהּ. כָּאָמוּר: וַאֲנִי אֶהְיֶה לָּהּ, נְאֻם יהוה, חוֹמַת אֵשׁ סָבִיב וּלְכָבוֹד אֶהְיֶה בְתוֹכָהּ:\nבָּרוּךְ אַתָּה יהוה, מְנַחֵם צִיּוֹן וּבוֹנֵה יְרוּשָׁלָיִם.","cond":["tishaaBeav"]},{"kind":"text","text":"אֶת צֶמַח דָּוִד עַבְדְּךָ מְהֵרָה תַצְמִיחַ, וְקַרְנוֹ תָּרוּם בִּישׁוּעָתֶךָ, כִּי לִישׁוּעָתְךָ קִוִּינוּ כָּל הַיּוֹם (וּמְצַפִּים לִישׁוּעָה). בָּרוּךְ אַתָּה יהוה, מַצְמִיחַ קֶרֶן יְשׁוּעָה.","cond":[]},{"kind":"text","text":"אָב הָרַחֲמָן, שְׁמַע קוֹלֵנוּ יהוה אֱלֹהֵינוּ, חוּס וְרַחֵם עָלֵינוּ, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ, כִּי אֵל שׁוֹמֵעַ תְּפִלּוֹת וְתַחֲנוּנִים אָתָּה, וּמִלְּפָנֶיךָ מַלְכֵּנוּ, רֵיקָם אַל תְּשִׁיבֵנוּ. חָנֵּנוּ וַעֲנֵנוּ וּשְׁמַע תְּפִלָּתֵנוּ.","cond":[]},{"kind":"instruction","text":"בתענית צבור יחיד אומר קודם כי אתה שומע:","cond":["taanit"]},{"kind":"special","text":"עֲנֵנוּ יהוה עֲנֵנוּ בְּיוֹם צוֹם תַּעֲנִיתֵנוּ, כִּי בְצָרָה גְדוֹלָה אֲנָחְנוּ. אַל תֵּפֶן אֶל רִשְׁעֵנוּ, וְאַל תַּסְתֵּר פָּנֶיךָ מִמֶּנּוּ, וְאַל תִּתְעַלַּם מִתְּחִנָּתֵנוּ. הֱיֵה נָא קָרוֹב לְשַׁוְעָתֵנוּ, יְהִי נָא חַסְדְּךָ לְנַחֲמֵנוּ, טֶרֶם נִקְרָא אֵלֶיךָ עֲנֵנוּ, כַּדָּבָר שֶׁנֶּאֱמַר: וְהָיָה טֶרֶם יִקְרָאוּ וַאֲנִי אֶעֱנֶה, עוֹד הֵם מְדַבְּרִים וַאֲנִי אֶשְׁמָע: כִּי אַתָּה יהוה הָעוֹנֶה בְּעֵת צָרָה, פּוֹדֶה וּמַצִּיל בְּכָל עֵת צָרָה וְצוּקָה.","cond":["taanit"]},{"kind":"special","text":"וַעֲנֵנוּ בּוֹרֵא עוֹלָם בְּמִדַּת הָרַחֲמִים, בּוֹחֵר בְּעַמּוֹ יִשְׂרָאֵל לְהוֹדִיעַ גָדְלוֹ וְהַדְרַת כְּבוֹדוֹ, שׁוֹמֵעַ תְּפִלָּה תֵּן טַל וּמָטָר עַל פְּנֵי הָאֲדָמָה, וְתַשְׂבִּיעַ אֶת הָעוֹלָם כֻּלּוֹ מִטּוּבֶךָ, וּמַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ וּמֵעֹשֶׁר מַתְּנַת יָדֶךָ, שְׁמוֹר וְהַצֵּל שָׁנָה זוֹ מִכָּל דָּבָר רָע, וּמִכָּל מִינִי מַשְׁחִית, וּמִכָּל מִינֵי פֻּרְעָנֻיּוֹת, וַעֲשֵׂה לָהּ תִּקְוָה וְאַחֲרִית שָׁלוֹם, חוּס וְרַחֵם עָלֵינוּ וְעַל כָּל תְּבוּאָתֵנוּ וּפֵרוֹתֵינוּ, וּבָרְכֵנוּ בְּגִשְׁמֵי בְרָכָה וְנִזְכֶּה לְחַיִּים וָשֹׂבַע וְשָׁלוֹם, כַּשָּׁנִים הַטּוֹבוֹת, וְהָסֵר מִמֶּנּוּ דֶּבֶר וְחֶרֶב וְרָעָב, וְחַיָּה רָעָה וּשְׁבִי וּבִזָּה, וְיֵצֶר הָרָע וָחֳלָיִם רָעִים וְקָשִׁים, וּמְאוֹרָעוֹת רָעִים וְקָשִׁים, וּגְזֹר עָלֵינוּ גְּזֵרוֹת טוֹבוֹת מִלְּפָנֶיךָ, וְיִגֹּלוּ רָחֲמֶיךָ עַל מִדּוֹתֶיךָ, וְתִתְנַהֵג עִם בָּנֶיךָ בְּמִדַּת הָרַחֲמִים, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ.","cond":["vaanenu"]},{"kind":"text","text":"כִּי אַתָּה שׁוֹמֵעַ תְּפִלַּת כָּל פֶּה. בָּרוּךְ אַתָּה יהוה, שׁוֹמֵעַ תְּפִלָּה.","cond":[]},{"kind":"text","text":"רְצֵה יהוה אֱלֹהֵינוּ בְּעַמְּךָ יִשְׂרָאֵל וְלִתְפִלָּתָם שְׁעֵה, וְהָשֵׁב אֶת הָעֲבוֹדָה לִדְבִיר בֵּיתֶךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם, מְהֵרָה בְּאַהֲבָה תְקַבֵּל בְּרָצוֹן. וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּךָ.","cond":[]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּיעַ וְיֵרָאֶה וְיֵרָצֶה, וְיִשָּׁמַע וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵנוּ וּפִקְדוֹנֵנו וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךְ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָָל עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶיךָ, לִפְלֵטָה, לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["rh"]},{"kind":"special","text":"רֹאשׁ הַחֹדֶשׁ הַזֶּה.","cond":["rh"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ, וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["rh"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּיעַ וְיֵרָאֶה וְיֵרָצֶה, וְיִשָּׁמַע וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵנוּ וּפִקְדוֹנֵנו וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךְ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָָל עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶיךָ, לִפְלֵטָה, לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["sucot"]},{"kind":"special","text":"חַג הַסֻּכּוֹת הַזֶּה.","cond":["sucot"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ, וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["sucot"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּיעַ וְיֵרָאֶה וְיֵרָצֶה, וְיִשָּׁמַע וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵנוּ וּפִקְדוֹנֵנו וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךְ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָָל עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶיךָ, לִפְלֵטָה, לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["pesach"]},{"kind":"special","text":"חַג הַמַּצּוֹת הַזֶּה.","cond":["pesach"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ, וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["pesach"]},{"kind":"text","text":"וְתֶחֱזֶינָה עֵינֵינוּ בְּשׁוּבְךָ לְצִיּוֹן בְּרַחֲמִים. בָּרוּךְ אַתָּה יהוה, הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן.","cond":[]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שָׁאַתָּה הוּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ לְעוֹלָם וָעֵד. צוּר חַיֵּינוּ, מָגֵן יִשְׁעֵנוּ אַתָּה הוּא לְדוֹר וָדוֹר. נוֹדֶה לְּךָ וּנְסַפֵּר תְּהִלָּתֶךָ עַל חַיֵּינוּ הַמְּסוּרִים בְּיָדֶךָ, וְעַל נִשְׁמוֹתֵינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּיךָ שֶׁבְּכָל יוֹם עִמָּנוּ, וְעַל נִפְלְאוֹתֶיךָ וְטוֹבוֹתֶיךָ שֶׁבְּכָל עֵת, עֶרֶב וָבֹקֶר וְצָהֳרָיִם. הַטּוֹב כִּי לֹא כָלוּ רַחֲמֶיךָ, וְהַמְרַחֵם כִּי לֹא תַמּוּ חֲסָדֶיךָ, כִּי מֵעוֹלָם קִוִּינוּ לָךְ.","cond":[]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מַתִּתְיָהוּ בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְהַשְׁכִּיחָם תּוֹרָתֶךָ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנֶךָ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּטְמֵאִים בְּיַד טְהוֹרִים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, וּלְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמֶךָ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כֵּן בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ לְהוֹדוֹת וּלְהַלֵּל לְשִׁמְךָ הַגָּדוֹל. (נ\"א: וְקָבְעוּ שְׁמוֹנַת יָמִים אֵלּוּ בְּהַלֵּל וּבְהוֹדָאָה וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה.)","cond":["chanuka"]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים, מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ, וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ, וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְּרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ (, וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה).","cond":["purim"]},{"kind":"text","text":"וְעַל כֻּלָּם יִתְבָּרַךְ וְיִתְרוֹמַם וְיִתְנַשֵּׂא שִׁמְךָ מַלְכֵּנוּ תָּמִיד לְעוֹלָם וָעֶד.","cond":[]},{"kind":"special","text":"וּכְתֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶךָ.","cond":["ayt"]},{"kind":"text","text":"וְכֹל הַחַיִּים יוֹדוּךָ סֶלָה, וִיהַלְלוּ וִיבָרְכוּ אֶת שִׁמְךָ הַגָּדוֹל בֶּאֱמֶת לְעוֹלָם כִּי טוֹב, הָאֵל יְשׁוּעָתֵנוּ וְעֶזְרָתֵנוּ סֶלָה, הָאֵל הַטּוֹב. בָּרוּך אַתָּה יהוה, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת.","cond":[]},{"kind":"text","text":"שִׂים שָׁלוֹם טוֹבָה וּבְרָכָה, חַיִּים חֵן וָחֶסֶד וְרַחֲמִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל עַמֶּךָ. בָּרְכֵנוּ אָבִינוּ כֻּלָּנוּ כְּאֶחָד (יַחַד) בְּאוֹר פָּנֶיךָ, כִּי בְאוֹר פָּנֶיךָ נָתַתָּ לָּנוּ יהוה אֱלֹהֵינוּ תּוֹרַת חַיִּים וְאַהֲבַת חֶסֶד, וּצְדָקָה וּבְרָכָה וְרַחֲמִים וְחַיִּים וְשָׁלוֹם. וְטוֹב יִהְיֶה בְעֵינֶיךָ לְבָרְכֵנוּ וּלְבָרֵךְ אֶת כָּל עַמְּךָ יִשְׂרָאֵל בְּכָל עֵת וּבְכָל שָׁעָה בִּשְׁלוֹמֶךָ (בְּרֹב עֹז וְשָׁלוֹם).","cond":[]},{"kind":"special","text":"בְּסֵפֶר חַיִּים, בְּרָכָה וְשָׁלוֹם, וּפַרְנָסָה טוֹבָה, וּגְזֵרוֹת טוֹבוֹת, יְשׁוּעוֹת וְנֶחָמוֹת, נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ, אֲנַחְנוּ וְכָל עַמְּךָ בֵּית יִשְׂרָאֵל, לְחַיִּים טוֹבִים וּלְשָׁלוֹם.","cond":["ayt"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הַמְבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם.","cond":[]},{"kind":"text","text":"יִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ. יהוה צוּרִי וְגוֹאֲלִי:","cond":[]},{"kind":"header","text":"וידוי לעיו\"כ","cond":["kipur"]},{"kind":"instruction","text":"סדר וידוי לערב יום הכיפורים","cond":["kipur"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, תָּבוֹא לְפָנֶיךָ תְּפִלָּתֵנוּ, וְאַל תִּתְעַלֵּם מִתְּחִנָּתֵנוּ, שֶׁאֵין אָנוּ עַזֵּי פָנִים וּקְשֵׁי עֹרֶף לוֹמַר לְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ צַדִּיקִים אֲנַחְנוּ וְלֹא חָטָאנוּ, אֲבָל אֲנַחְנוּ וַאֲבוֹתֵינוּ חָטָאנוּ.\nאָשַׁמְנוּ, בָּגַדְנוּ, גָּזַלְנוּ, דִּבַּרְנוּ דֹפִי. הֶעֱוִינוּ, וְהִרְשַׁעְנוּ, זַדְנוּ, חָמַסְנוּ, טָפַלְנוּ שֶׁקֶר. יָעַצְנוּ רָע, כִּזַּבְנוּ, לַצְנוּ, מָרַדְנוּ, נִאַצְנוּ, סָרַרְנוּ, עָוִינוּ, פָּשַׁעְנוּ, צָרַרְנוּ, קִשִּׁינוּ עֹרֶף. רָשַׁעְנוּ, שִׁחַתְנוּ, תִּעַבְנוּ, תָּעִינוּ, תִּעְתַּעְנוּ.\nסַרְנוּ מִמִּצְוׂתֶיךָ וּמִמִּשְׁפָּטֶיךָ הַטּוֹבִים וְלֹא שָׁוָה-לָנוּ. וְאַתָּה צַדִּיק עַל כָּל הַבָּא עָלֵינוּ, כִּי אֱמֶת עָשִׂיתָ, וַאֲנַחְנוּ הִרְשָׁעְנוּ:\nמַה נֹּאמַר לְפָנֶיךָ יוֹשֵׁב מָרוֹם, וּמַה נְּסַפֵּר לְפָנֶיךָ שׁוֹכֵן שְׁחָקִים, הֲלֹא כָּל הַנִּסְתָּרוֹת וְהַנִּגְלוֹת אַתָּה יוֹדֵעַ.\n\nאַתָּה יוֹדֵעַ רָזֵי עוֹלָם וְתַעֲלוּמוֹת סִתְרֵי כָל חָי. אַתָּה חוֹפֵשׂ כָּל חַדְרֵי בָטֶן וּבוֹחֵן כְּלָיוֹת וָלֵב. אֵין דָּבָר נֶעְלָם מִמֶּךָּ, וְאֵין נִסְתָּר מִנֶּגֶד עֵינֶיךָ.\nוּבְכֵן יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּסְלַח לָנוּ עַל כָּל חַטֹּאתֵינוּ, וְתִמְחַל לָנוּ עַל כָּל עֲוׂנוֹתֵינוּ, וּתְכַפֵּר לָנוּ עַל כָּל פְּשָׁעֵינוּ:\n\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּאֹנֶס וּבְרָצוֹן,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּאִמּוּץ הַלֵּב.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּבְלִי דָעַת,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּבִטּוּי שְׂפָתָיִם.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּגָלוּי וּבַסָּתֶר,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּגִלּוּי עֲרָיוֹת.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּדִבּוּר פֶּה,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּדַעַת וּבְמִרְמָה.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּהִרְהוּר הַלֵּב,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּהוֹנָאַת רֵעַ.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּוִדּוּי פֶּה,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּוְעִידַת זְנוּת.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּזָדוֹן וּבִשְׁגָגָה,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּזִלְזוּל הוֹרִים וּמוֹרִים.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּחֹזֶק יָד,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּחִלּוּל הַשֵּׁם.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּטִפְּשׁוּת פֶּה,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּטֻמְאַת שְׂפָתָיִם.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּיֵצֶר הָרָע,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּיוֹדְעִים וּבְלֹא יוֹדְעִים.","cond":["kipur"]},{"kind":"special","text":"וְעַל כֻּלָּם, אֱלוֹהַּ סְלִיחוֹת, סְלַח לָנוּ, מְחַל לָנוּ, כַּפֶּר לָנוּ.","cond":["kipur"]},{"kind":"text","text":"עַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּכַפַּת שֹׁחַד,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּכַחַשׁ וּבְכָזָב.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּלָשׁוֹן הָרָע,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּלָצוֹן.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּמַשָּׂא וּבְמַתָּן,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּמַאֲכָל וּבְמִשְׁתֶּה.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּנֶשֶׁךְ וּבְמַרְבִּית,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּנְטִיַּת גָּרוֹן.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּשִׂקּוּר עָיִן,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּשִׂיחַ שִׂפְתוֹתֵינוּ.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּעֵינַיִם רָמוֹת,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּעַזּוּת מֶצַח.","cond":["kipur"]},{"kind":"special","text":"וְעַל כֻּלָּם, אֱלוֹהַּ סְלִיחוֹת, סְלַח לָנוּ, מְחַל לָנוּ, כַּפֶּר לָנוּ.","cond":["kipur"]},{"kind":"text","text":"עַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּפְרִיקַת עֹל,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּפְלִילוּת.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּצְדִיַּת רֵעַ,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּצָרוּת עָיִן.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּקַלּוּת רֹאשׁ,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּקַשְׁיוּת עֹרֶף.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּרִיצַת רַגְלַיִם לְהָרַע,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּרְכִילוּת.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּשְׁבוּעַת שָׁוְא,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּשִׂנְאַת חִנָּם.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּתְשׂוּמֶת יָד,\nוְעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּתִמְהוֹן לֵבָב.","cond":["kipur"]},{"kind":"special","text":"וְעַל כֻּלָּם, אֱלוֹהַּ סְלִיחוֹת, סְלַח לָנוּ, מְחַל לָנוּ, כַּפֶּר לָנוּ.","cond":["kipur"]},{"kind":"text","text":"וְעַל חֲטָאִים שֶׁאָנוּ חַיָּבִים עֲלֵיהֶם עוֹלָה,\nוְעַל חֲטָאִים שֶׁאָנוּ חַיָּבִים עֲלֵיהֶם חַטָּאת,\nוְעַל חֲטָאִים שֶׁאָנוּ חַיָּבִים עֲלֵיהֶם קָרְבָּן עוֹלֶה וְיוֹרֵד,\nוְעַל חֲטָאִים שֶׁאָנוּ חַיָּבִים עֲלֵיהֶם אָשָׁם וַדַּאי וְתָלוּי,\nוְעַל חֲטָאִים שֶׁאָנוּ חַיָּבִים עֲלֵיהֶם מַכַּת מַרְדוּת,\nוְעַל חֲטָאִים שֶׁאָנוּ חַיָּבִים עֲלֵיהֶם מַלְקוּת אַרְבָּעִים,\nוְעַל חֲטָאִים שֶׁאָנוּ חַיָּבִים עֲלֵיהֶם מִיתָה בִּידֵי שָׁמָיִם,\nוְעַל חֲטָאִים שֶׁאָנוּ חַיָּבִים עֲלֵיהֶם כָּרֵת וַעֲרִירִי,\nוְעַל חֲטָאִים שֶׁאָנוּ חַיָּבִים עֲלֵיהֶם אַרְבַּע מִיתוֹת בֵּית דִּין: סְקִילָה, שְׂרֵפָה, הֶרֶג, וְחֶנֶק,\nעַל מִצְוַת עֲשֵׂה וְעַל מִצְוַת לֹא תַעֲשֶׂה, בֵּין שֶׁיֵּשׁ בָּהּ קוּם עֲשֵׂה וּבֵין שֶׁאֵין בָּהּ קוּם עֲשֵׂה, אֶת הַגְּלוּיִם לָנוּ וְאֶת שֶׁאֵינָם גְּלוּיִם לָנוּ: אֶת הַגְּלוּיִם לָנוּ כְּבָר אֲמַרְנוּם לְפָנֶיךָ וְהוֹדִינוּ לְךָ עֲלֵיהֶם, וְאֶת שֶׁאֵינָם גְּלוּיִם לָנוּ, לְפָנֶיךָ הֵם גְּלוּיִם וִידוּעִים, כַּדָּבָר שֶׁנֶּאֱמַר: הַנִּסְתָּרֹת לַיהוה אֱלֹהֵינוּ, וְהַנִּגְלֹת לָנוּ וּלְבָנֵינוּ עַד עוֹלָם, לַעֲשׂוֹת אֶת כָּל דִּבְרֵי הַתּוֹרָה הַזֹּאת: כִּי אַתָּה סָלְחָן לְיִשְׂרָאֵל וּמָחֳלָן לְשִׁבְטֵי יְשֻׁרוּן בְּכָל דּוֹר וָדוֹר, וּמִבַּלְעָדֶיךָ אֵין לָנוּ מֶלֶךְ מוֹחֵל וְסוֹלֵחַ.\n\nאֱלֹהַי, עַד שֶׁלּא נוֹצַרְתִּי אֵינִי כְדַאי, וְעַכְשָׁו שֶׁנּוֹצַרְתִּי כְּאִלּוּ לֹא נוֹצַרְתִּי. עָפָר אֲנִי בְּחַיַּי, קַל וָחֹמֶר בְּמִיתָתִי. הֲרֵי אֲנִי לְפָנֶיךָ כִּכְלִי מָלֵא בוּשָׁה וּכְלִמָּה. יְהִי רָצוֹן מִלְּפָנֶיךָ, יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁלֹּא אֶחֱטָא עוֹד, וּמַה שֶּׁחָטָאתִי לְפָנֶיךָ מְחֹק בְּרַחֲמֶיךָ הָרַבִּים, אֲבָל לֹא עַל יְדֵי יִסּוּרִים וָחֳלָיִים רָעִים.","cond":["kipur"]},{"kind":"text","text":"אֱלֹהַי, נְצֹר לְשׁוֹנִי מֵרָע וּשְׂפָתַי מִדַּבֵּר מִרְמָה, וְלִמְקַלְלַי נַפְשִׁי תִדֹּם, וְנַפְשִׁי כֶּעָפָר לַכֹּל תִּהְיֶה. פְּתַח לִבִּי בּתוֹרָתֶךָ, וְאַחֲרֵי מִצְוׂתֶיךָ תִּרְדֹף נַפְשִׁי. וְכָל הַקָּמִים וְהַחוֹשְׁבִים עָלַי לְרָעָה, מְהֵרָה הָפֵר עֲצָתָם וְקַלְקֵל מַחֲשַׁבְתָּם.\n(יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁלֹּא תַעֲלֶה קִנְאַת אָדָם עָלַי וְלֹא קִנְאָתִי עַל אֲחֵרִים, וְשֶׁלֹּא אֶכְעוֹס הַיּוֹם וְשֶׁלֹּא אַכְעִיסֶךָ. וְתַצִּילֵנִי מִיֵּצֶר הָרָע, וְתֵן בְּלִבִּי הַכְנָעָה וַעֲנָוָה. מַלְכֵּנוּ וֵאלֹהֵינוּ אֱלוֹהַּ כָּל בָּשָׂר, יַחֵד שִׁמְךָ בְּעוֹלָמֶךָ, בְּנֵה עִירֶךָ, יַסֵּד בֵּיתֶךָ וְשַׁכְלֵל הֵיכָלֶךָ, וְקַבֵּץ קִבּוּץ גָלֻיּוֹת וּפְדֵה צֹאנֶךָ וְשַׂמַּח עָדָתֶךָ.)\nעֲשֵׂה לְמַעַן שְׁמֶךָ, עֲשֵׂה לְמַעַן יְמִינֶךָ, עֲשֵׂה לְמַעַן תּוֹרָתֶךָ, עֲשֵׂה לְמַעַן קְדֻשָּׁתֶךָ. לְמַעַן יֵחָלְצוּן יְדִידֶיךָ הוֹשִׁיעָה יְמִינְךָ וַעֲנֵנִי:\nיִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:","cond":[]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁיִּבָּנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵינוּ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתֶךָ, וְשָׁם נַעֲבָדְךָ בְּיִרְאָה כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמוֹנִיּוֹת. וְעָרְבָה לַיהוה מִנְחַת יְהוּדָה וִירוּשָׁלָיִם כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמֹנִיּוֹת:","cond":[]},{"kind":"header","text":"חזרת הש\"ץ","cond":[]},{"kind":"instruction","text":"חזרת הש\"ץ","cond":[]},{"kind":"text","text":"כִּי שֵׁם יהוה אֶקְרָא, הָבוּ גֹדֶל לֵאלֹהֵינוּ:\nאֲדֹנָי, שְׂפָתַי תִּפְתָּח, וּפִי יַגִּיד תְּהִלָּתֶךָ:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק, וֵאלֹהֵי יַעֲקֹב, הָאֵל הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, וְקוֹנֵה הַכֹּל, וְזוֹכֵר חַסְדֵי אָבוֹת, וּמֵבִיא גוֹאֵל לִבְנֵי בְנֵיהֶם לְמַעַן שְׁמוֹ בְּאַהֲבָה.","cond":[]},{"kind":"special","text":"זָכְרֵנוּ לְחַיִּים, מֶלֶךְ חָפֵץ בַּחַיִּים, וְכָתְבֵנוּ בְּסֵפֶר הַחַיִּים, לְמַעַנְךָ אֱלֹהִים חַיִּים.","cond":["ayt"]},{"kind":"text","text":"מֶלֶךְ עוֹזֵר וּמוֹשִׁיעַ וּמָגֵן. בָּרוּךְ אַתָּה יהוה, מָגֵן אַבְרָהָם.","cond":[]},{"kind":"text","text":"אַתָּה גִּבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֵּה מֵתִים אַתָּה רַב לְהוֹשִׁיעַ,","cond":[]},{"kind":"summer","text":"מוֹרִיד הַטָּל,","cond":["summerTal"]},{"kind":"winter","text":"מַשִּׁיב הָרוּחַ וּמוֹרִיד הַגֶּשֶׁם,","cond":["winterTal"]},{"kind":"text","text":"מְכַלְכֵּל חַיִּים בְּחֶסֶד, מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים, סוֹמֵךְ נוֹפְלִים, וְרוֹפֵא חוֹלִים וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמוּנָתוֹ לִישֵׁנֵי עָפָר. מִי כָמוֹךָ בַּעַל גְּבוּרוֹת וּמִי דּוֹמֶה לָךְ, מֶלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִיחַ יְשׁוּעָה.","cond":[]},{"kind":"special","text":"מִי כָמוֹךָ אַב הָרַחֲמָן, זוֹכֵר יְצוּרָיו לְחַיִּים בְּרַחֲמִים.","cond":["ayt"]},{"kind":"text","text":"וְנֶאֱמָן אַתָּה לְהַחֲיוֹת מֵתִים. בָּרוּךְ אַתָּה יהוה, מְחַיֵּה הַמֵּתִים.","cond":[]},{"kind":"header","text":"קדושה","cond":[]},{"kind":"instruction","text":"קדושה בחזרת הש\"ץ:","cond":[]},{"kind":"text","text":"נַקְדִּישָׁךְ וְנַעֲרִיצָךְ כְּנֹעַם שִׂיחַ סוֹד שַׂרְפֵי קֹדֶשׁ הַמְשַׁלְּשִׁים לְךָ קְדֻשָּׁה, כַּכָּתוּב עַל יַד נְבִיאֶךָ: וְקָרָא זֶה אֶל זֶה וְאָמַר:\nקו\"ח: קָדוֹשׁ, קָדוֹשׁ, קָדוֹשׁ יהוה צְבָאוֹת, מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ:\nחזן: לְעֻמָּתָם מְשַׁבְּחִים וְאוֹמְרִים:\nקו\"ח: בָּרוּךְ כְּבוֹד יהוה מִמְּקוֹמוֹ:\nחזן: וּבְדִבְרֵי קָדְשְׁךָ כָּתוּב לֵאמֹר:\nקו\"ח: יִמְלֹך יהוה לְעוֹלָם, אֱלֹהַיִך צִיּוֹן לְדֹר וָדֹר, הַלְלוּיָהּ:","cond":[]},{"kind":"text","text":"אַתָּה קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ וּקְדוֹשִׁים בְּכָל יוֹם יְהַלְלוּךָ סֶּלָה, כִּי אֵל מֶלֶךְ גָּדוֹל וְקָדוֹשׁ אָתָּה.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הָאֵל הַקָּדוֹשׁ.","cond":["noayt"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יהוה, הַמֶּלֶךְ הַקָּדוֹשׁ.","cond":["ayt"]},{"kind":"text","text":"אַתָּה חוֹנֵן לְאָדָם דַּעַת וּמְלַמֵּד לֶאֱנוֹשׁ בִּינָה.","cond":[]},{"kind":"text","text":"חָנֵּנוּ מִאִתְּךָ חָכְמָה בִּינָה וָדָעַת","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, חוֹנֵן הַדָּעַת.","cond":[]},{"kind":"text","text":"הֲשִׁיבֵנוּ אָבִינוּ לְתוֹרָתֶךָ, וְקָרְבֵנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶך, וְהַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ. בָּרוּךְ אַתָּה יהוה, הָרוֹצֶה בִּתְשׁוּבָה.","cond":[]},{"kind":"text","text":"סְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ, כִּי אֵל טוֹב וְסַלָּח אָתָּה. בָּרוּךְ אַתָּה יהוה, חַנּוּן הַמַּרְבֶּה לִסְלֹחַ.","cond":[]},{"kind":"text","text":"רְאֵה נָא בְעָנְיֵנוּ, וְרִיבָה רִיבֵנוּ, וּגְאָלֵנוּ גְאֻלָּה שְׁלֵמָה מְהֵרָה לְמַעַן שְׁמֶךָ, כִּי אֵל גּוֹאֵל חָזָק אָתָּה. בָּרוּךְ אַתָּה יהוה, גּוֹאֵל יִשְׂרָאֵל.","cond":[]},{"kind":"instruction","text":"בתענית צבור החזן אומר:","cond":["taanit"]},{"kind":"special","text":"עֲנֵנוּ יהוה עֲנֵנוּ בְּיוֹם צוֹם תַּעֲנִיתֵנוּ, כִּי בְצָרָה גְדוֹלָה אֲנָחְנוּ. אַל תֵּפֶן אֶל רִשְׁעֵנוּ, וְאַל תַּסְתֵּר פָּנֶיךָ מִמֶּנּוּ, וְאַל תִּתְעַלַּם מִתְּחִנָּתֵנוּ. הֱיֵה נָא קָרוֹב לְשַׁוְעָתֵנוּ, יְהִי נָא חַסְדְּךָ לְנַחֲמֵנוּ, טֶרֶם נִקְרָא אֵלֶיךָ עֲנֵנוּ, כַּדָּבָר שֶׁנֶּאֱמַר: וְהָיָה טֶרֶם יִקְרָאוּ וַאֲנִי אֶעֱנֶה, עוֹד הֵם מְדַבְּרִים וַאֲנִי אֶשְׁמָע: כִּי אַתָּה יהוה הָעוֹנֶה בְּעֵת צָרָה, פּוֹדֶה וּמַצִּיל בְּכָל עֵת צָרָה וְצוּקָה. בָּרוּךְ אַתָּה יהוה, הָעוֹנֶה לְעַמּוֹ יִשְׂרָאֵל בְּעֵת צָרָה.","cond":["taanit"]},{"kind":"text","text":"רְפָאֵנוּ יהוה וְנֵרָפֵא, הוֹשִׁיעֵנוּ וְנִוָּשֵׁעָה כִּי תְהִלָּתֵנוּ אָתָּה, וְהַעֲלֵה (אֲרוּכָה וּמַרְפֵּא לְכָל תַּחֲלוּאֵינוּ וּלְכָל מַכְאוֹבֵינוּ) רְפוּאָה שְׁלֵמָה לְכָל מַכּוֹתֵינוּ. כִּי אֵל מֶלֶךְ רוֹפֵא נֶאֱמָן וְרַחֲמָן אָתָּה. בָּרוּךְ אַתָּה יהוה, רוֹפֵא חוֹלֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"בָּרֵך עָלֵינוּ יהוה אֱלֹהֵינוּ אֶת הַשָּׁנָה הַזֹּאת וְאֶת כָּל מִינֵי תְבוּאָתָהּ לְטוֹבָה, וְתֵן","cond":[]},{"kind":"summer","text":"בְּרָכָה","cond":["summerBracha"]},{"kind":"winter","text":"טַל וּמָטָר לִבְרָכָה","cond":["winterBracha"]},{"kind":"text","text":"עַל פְּנֵי הָאֲדָמָה וְשַׂבְּעֵנוּ מִטּוּבָהּ, וּבָרֵךְ שְׁנָתֵנוּ כַּשָּׁנִים הַטּוֹבוֹת לִבְרָכָה. כִּי אֵל טוֹב וּמֵטִיב אַתָּה וּמְבָרֵךְ הַשָּׁנִים. בָּרוּךְ אַתָּה יהוה, מְבָרֵךְ הַשָּׁנִים.","cond":[]},{"kind":"text","text":"תְּקַע בְּשׁוֹפָר גָּדוֹל לְחֵרוּתֵנוּ וְשָׂא נֵס לְקַבֵּץ גָּלֻיּוֹתֵינוּ, וְקַבְּצֵנוּ יַחַד מְהֵרָה מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ לְאַרְצֵנוּ. בָּרוּךְ אַתָּה יהוה, מְקַבֵּץ נִדְחֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"הָשִׁיבָה שׁוֹפְטֵינוּ כְּבָרִאשׁוֹנָה וְיוֹעֲצֵינוּ כְּבַתְּחִלָּה, וְהָסֵר מִמֶּנּוּ יָגוֹן וַאֲנָחָה, וּמְלֹךְ עָלֵינוּ מְהֵרָה אַתָּה יהוה לְבַדְּךָ בְּחֶסֶד וּבְרַחֲמִים, בְּצֶדֶק וּבְמִשְׁפָט.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, מֶלֶךְ אוֹהֵב צְדָקָה וּמִשְׁפָּט.","cond":["noayt"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יהוה, הַמֶּלֶךְ הַמִּשְׁפָּט.","cond":["ayt"]},{"kind":"text","text":"וְלַמַּלְשִׁינִים אַל תְּהִי תִקְוָה, וְכָל הַמִּינִים כְּרֶגַע יֹאבֵדוּ. וְכָל אוֹיְבֵי עַמְּךָ מְהֵרָה יִכָּרֵתוּ, וְהַזֵּדִים מְהֵרָה תְעַקֵּר וּתְשַׁבֵּר וּתְמַגֵּר וּתְכַלֵּם וְתַשְׁפִּילֵם וְתַכְנִיעֵם בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יהוה, שׁוֹבֵר אוֹיְבִים וּמַכְנִיעַ זֵדִים.","cond":[]},{"kind":"text","text":"עַל הַצַּדִּיקִים וְעַל הַחֲסִידִים, וְעַל זִקְנֵי שְׁאֵרִית עַמְּךָ בֵּית יִשְׂרָאֵל, וְעַל פְּלֵיטַת בֵּית סוֹפרֵיהֶם, וְעַל גֵּרֵי הַצֶדֶק וְעָלֵינוּ, יֶהֱמוּ נָא רַחֲמֶיךָ יהוה אֱלֹהֵינוּ, וְתֵן שָׂכָר טוֹב לְכָל הַבּוֹטְחִים בְּשִׁמְךָ בֶּאֱמֶת, וְשִׂים חֶלְקֵנוּ עִמָּהֶם וּלְעוֹלָם לֹא נֵבוֹשׁ כִּי בְךָ בָטָחְנוּ וְעַל חַסְדְּךָ הַגָּדוֹל בֶּאֱמֶת (וּבְתָמִים) נִשְׁעַנּוּ. בָּרוּךְ אַתָּה יהוה, מִשְׁעָן וּמִבְטָח לַצַּדִּיקִים.","cond":[]},{"kind":"text","text":"וְלִירוּשָׁלַיִם עִירְךָ בְּרַחֲמִים תָּשׁוּב וְתִשְׁכֹּן בְּתוֹכָהּ כַּאֲשֶׁר דִּבַּרְתָּ, וּבְנֵה אוֹתָהּ בְּקָרוֹב בְּיָמֵינוּ בִּנְיָן עוֹלָם, וְכִסֵּא דָוִד עַבְדְּךָ מְהֵרָה לְתוֹכָהּ תָּכִין.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, בּוֹנֵה יְרוּשָׁלָיִם.","cond":["noTishaaBeav"]},{"kind":"special","text":"נַחֵם יהוה אֱלֹהֵינוּ אֶת אֲבֵלֵי צִיּוֹן וְאֶת אֲבֵלֵי יְרוּשָלַיִם וְאֶת הָעִיר הָאֲבֵלָה וְהַחֲרֵבָה וְהַבְּזוּיָה וְהַשּׁוֹמְמָה. הָאֲבֵלָה מִבְּלִי בָנֶיהָ וְהַחֲרֵבָה מִמְּעוֹנוֹתֶיהָ, וְהַבְּזוּיָה מִכְּבוֹדָהּ, וְהַשּׁוֹמְמָה מֵאֵין יוֹשֵׁב. וְהִיא יוֹשֶׁבֶת וְראשָׁהּ חָפוּי כְּאִשָּׁה עֲקָרָה שֶׁלֹּא יָלָדָה. וַיְבַלְּעוּהָ לִגְיוֹנוֹת, וַיִּירָשׁוּהָ עוֹבְדֵי זָרִים, וַיָּטִילוּ אֶת עַמְּךָ יִשְׂרָאֵל לֶחָרֶב, וַיַּהַרְגוּ בְזָדוֹן חֲסִידֵי עֶלְיוֹן. עַל כֵּן צִיּוֹן בְּמַר תִּבְכֶּה, וִירוּשָׁלַיִם תִּתֵּן קוֹלָהּ. לִבִּי לִבִּי עַל חַלְלֵיהֶם, מֵעַי מֵעַי עַל חַלְלֵיהֶם, כִּי אַתָּה יהוה בָּאֵשׁ הִצַּתָּהּ, וּבָאֵשׁ אַתָּה עָתִיד לִבְנוֹתָהּ. כָּאָמוּר: וַאֲנִי אֶהְיֶה לָּהּ, נְאֻם יהוה, חוֹמַת אֵשׁ סָבִיב וּלְכָבוֹד אֶהְיֶה בְתוֹכָהּ:\nבָּרוּךְ אַתָּה יהוה, מְנַחֵם צִיּוֹן וּבוֹנֵה יְרוּשָׁלָיִם.","cond":["tishaaBeav"]},{"kind":"text","text":"אֶת צֶמַח דָּוִד עַבְדְּךָ מְהֵרָה תַצְמִיחַ, וְקַרְנוֹ תָּרוּם בִּישׁוּעָתֶךָ, כִּי לִישׁוּעָתְךָ קִוִּינוּ כָּל הַיּוֹם (וּמְצַפִּים לִישׁוּעָה). בָּרוּךְ אַתָּה יהוה, מַצְמִיחַ קֶרֶן יְשׁוּעָה.","cond":[]},{"kind":"text","text":"אָב הָרַחֲמָן, שְׁמַע קוֹלֵנוּ יהוה אֱלֹהֵינוּ, חוּס וְרַחֵם עָלֵינוּ, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ, כִּי אֵל שׁוֹמֵעַ תְּפִלּוֹת וְתַחֲנוּנִים אָתָּה, וּמִלְּפָנֶיךָ מַלְכֵּנוּ, רֵיקָם אַל תְּשִׁיבֵנוּ. חָנֵּנוּ וַעֲנֵנוּ וּשְׁמַע תְּפִלָּתֵנוּ.","cond":[]},{"kind":"special","text":"וַעֲנֵנוּ בּוֹרֵא עוֹלָם בְּמִדַּת הָרַחֲמִים, בּוֹחֵר בְּעַמּוֹ יִשְׂרָאֵל לְהוֹדִיעַ גָדְלוֹ וְהַדְרַת כְּבוֹדוֹ, שׁוֹמֵעַ תְּפִלָּה תֵּן טַל וּמָטָר עַל פְּנֵי הָאֲדָמָה, וְתַשְׂבִּיעַ אֶת הָעוֹלָם כֻּלּוֹ מִטּוּבֶךָ, וּמַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ וּמֵעֹשֶׁר מַתְּנַת יָדֶךָ, שְׁמוֹר וְהַצֵּל שָׁנָה זוֹ מִכָּל דָּבָר רָע, וּמִכָּל מִינִי מַשְׁחִית, וּמִכָּל מִינֵי פֻּרְעָנֻיּוֹת, וַעֲשֵׂה לָהּ תִּקְוָה וְאַחֲרִית שָׁלוֹם, חוּס וְרַחֵם עָלֵינוּ וְעַל כָּל תְּבוּאָתֵנוּ וּפֵרוֹתֵינוּ, וּבָרְכֵנוּ בְּגִשְׁמֵי בְרָכָה וְנִזְכֶּה לְחַיִּים וָשֹׂבַע וְשָׁלוֹם, כַּשָּׁנִים הַטּוֹבוֹת, וְהָסֵר מִמֶּנּוּ דֶּבֶר וְחֶרֶב וְרָעָב, וְחַיָּה רָעָה וּשְׁבִי וּבִזָּה, וְיֵצֶר הָרָע וָחֳלָיִם רָעִים וְקָשִׁים, וּמְאוֹרָעוֹת רָעִים וְקָשִׁים, וּגְזֹר עָלֵינוּ גְּזֵרוֹת טוֹבוֹת מִלְּפָנֶיךָ, וְיִגֹּלוּ רָחֲמֶיךָ עַל מִדּוֹתֶיךָ, וְתִתְנַהֵג עִם בָּנֶיךָ בְּמִדַּת הָרַחֲמִים, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ.","cond":["vaanenu"]},{"kind":"text","text":"כִּי אַתָּה שׁוֹמֵעַ תְּפִלַּת כָּל פֶּה. בָּרוּךְ אַתָּה יהוה, שׁוֹמֵעַ תְּפִלָּה.","cond":[]},{"kind":"text","text":"רְצֵה יהוה אֱלֹהֵינוּ בְּעַמְּךָ יִשְׂרָאֵל וְלִתְפִלָּתָם שְׁעֵה, וְהָשֵׁב אֶת הָעֲבוֹדָה לִדְבִיר בֵּיתֶךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם, מְהֵרָה בְּאַהֲבָה תְקַבֵּל בְּרָצוֹן. וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּךָ.","cond":[]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּיעַ וְיֵרָאֶה וְיֵרָצֶה, וְיִשָּׁמַע וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵנוּ וּפִקְדוֹנֵנו וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךְ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָָל עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶיךָ, לִפְלֵטָה, לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["rh"]},{"kind":"special","text":"רֹאשׁ הַחֹדֶשׁ הַזֶּה.","cond":["rh"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ, וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["rh"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּיעַ וְיֵרָאֶה וְיֵרָצֶה, וְיִשָּׁמַע וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵנוּ וּפִקְדוֹנֵנו וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךְ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָָל עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶיךָ, לִפְלֵטָה, לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["sucot"]},{"kind":"special","text":"חַג הַסֻּכּוֹת הַזֶּה.","cond":["sucot"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ, וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["sucot"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּיעַ וְיֵרָאֶה וְיֵרָצֶה, וְיִשָּׁמַע וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵנוּ וּפִקְדוֹנֵנו וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךְ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָָל עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶיךָ, לִפְלֵטָה, לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["pesach"]},{"kind":"special","text":"חַג הַמַּצּוֹת הַזֶּה.","cond":["pesach"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ, וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["pesach"]},{"kind":"text","text":"וְתֶחֱזֶינָה עֵינֵינוּ בְּשׁוּבְךָ לְצִיּוֹן בְּרַחֲמִים. בָּרוּךְ אַתָּה יהוה, הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן.","cond":[]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שָׁאַתָּה הוּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ לְעוֹלָם וָעֵד. צוּר חַיֵּינוּ, מָגֵן יִשְׁעֵנוּ אַתָּה הוּא לְדוֹר וָדוֹר. נוֹדֶה לְּךָ וּנְסַפֵּר תְּהִלָּתֶךָ עַל חַיֵּינוּ הַמְּסוּרִים בְּיָדֶךָ, וְעַל נִשְׁמוֹתֵינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּיךָ שֶׁבְּכָל יוֹם עִמָּנוּ, וְעַל נִפְלְאוֹתֶיךָ וְטוֹבוֹתֶיךָ שֶׁבְּכָל עֵת, עֶרֶב וָבֹקֶר וְצָהֳרָיִם. הַטּוֹב כִּי לֹא כָלוּ רַחֲמֶיךָ, וְהַמְרַחֵם כִּי לֹא תַמּוּ חֲסָדֶיךָ, כִּי מֵעוֹלָם קִוִּינוּ לָךְ.","cond":[]},{"kind":"header","text":"מודים דרבנן","cond":[]},{"kind":"instruction","text":"מודים דרבנן:","cond":[]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שָׁאַתָּה הוּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי כָל בָּשָׂר, יוֹצְרֵנוּ יוֹצֵר בְּרֵאשִׁית, בְּרָכוֹת וְהוֹדָאוֹת לְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ עַל שֶׁהֶחֱיִיתָנוּ וְקִיַּמְתָּנוּ. כֵּן תְּחַיֵּנוּ וּתְקַיְּמֵנוּ, וְתֶאֱסוֹף גָּלֻיּוֹתֵינוּ לְחַצְרוֹת קָדְשֶׁךָ, לִשְׁמוֹר חֻקֶּיךָ, וְלַעֲשׂוֹת רְצוֹנֶךָ, וּלְעָבְדְךָ בְּלֵבָב שָׁלֵם, עַל שֶׁאֲנַחְנוּ מוֹדִים לָךְ. בָּרוּךְ אֵל הַהוֹדָאוֹת.","cond":[]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מַתִּתְיָהוּ בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְהַשְׁכִּיחָם תּוֹרָתֶךָ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנֶךָ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּטְמֵאִים בְּיַד טְהוֹרִים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, וּלְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמֶךָ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כֵּן בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ לְהוֹדוֹת וּלְהַלֵּל לְשִׁמְךָ הַגָּדוֹל. (נ\"א: וְקָבְעוּ שְׁמוֹנַת יָמִים אֵלּוּ בְּהַלֵּל וּבְהוֹדָאָה וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה.)","cond":["chanuka"]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים, מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ, וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ, וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְּרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ (, וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה).","cond":["purim"]},{"kind":"text","text":"וְעַל כֻּלָּם יִתְבָּרַךְ וְיִתְרוֹמַם וְיִתְנַשֵּׂא שִׁמְךָ מַלְכֵּנוּ תָּמִיד לְעוֹלָם וָעֶד.","cond":[]},{"kind":"special","text":"וּכְתֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶךָ.","cond":["ayt"]},{"kind":"text","text":"וְכֹל הַחַיִּים יוֹדוּךָ סֶלָה, וִיהַלְלוּ וִיבָרְכוּ אֶת שִׁמְךָ הַגָּדוֹל בֶּאֱמֶת לְעוֹלָם כִּי טוֹב, הָאֵל יְשׁוּעָתֵנוּ וְעֶזְרָתֵנוּ סֶלָה, הָאֵל הַטּוֹב. בָּרוּך אַתָּה יהוה, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת.","cond":[]},{"kind":"header","text":"ברכת כהנים","cond":["taanit"]},{"kind":"instruction","text":"ברכת כהנים לחזרת הש\"ץ:\n\nאם לא עלו כהנים לדוכן הש\"ץ אומר או\"א (נמצא בהמשך).\n\nאם עלו שני כהנים לדוכן קוראים להם - כֹּהֲנִים:\n\nהכהנים מברכים:","cond":["taanit"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בִּקְדֻשָּׁתוֹ שֶׁל אַהֲרֹן, וְצִוָּנוּ לְבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בְּאַהֲבָה.\n\nיְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ:\nיָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ:\nיִשָּׂא יהוה פָּנָיו אֵלֶיךָ וְיָשֵׂם לְךָ שָׁלוֹם:","cond":["taanit"]},{"kind":"instruction","text":"הקהל אומר:","cond":["taanit"]},{"kind":"text","text":"אַדִּיר בַּמָּרוֹם שׁוֹכֵן בִּגְבוּרָה, אַתָּה שָׁלוֹם וְשִׁמְךָ שָׁלוֹם. יְהִי רָצוֹן שֶׁתָּשִׂים עָלֵינוּ וְעַל כָּל עַמְּךָ בֵּית יִשְׂרָאֵל חַיִּים וּבְרָכָה לְמִשְׁמֶרֶת שָׁלוֹם.","cond":["taanit"]},{"kind":"instruction","text":"הכהנים אומרים","cond":["taanit"]},{"kind":"text","text":"רִבּוֹנוֹ שֶׁל עוֹלָם, עָשִׂינוּ מַה שֶּׁגָּזַרְתָּ עָלֵינוּ, אַף אַתָּה עֲשֵׂה עִמָּנוּ כְּמוֹ שֶׁהִבְטַחְתָּנוּ: הַשְׁקִיפָה מִמְּעוֹן קָדְשְׁךָ מִן הַשָּׁמַיִם, וּבָרֵךְ אֶת עַמְּךָ אֶת יִשְׂרָאֵל, וְאֵת הָאֲדָמָה אֲשֶׁר נָתַתָּה לָנוּ, כַּאֲשֶׁר נִשְׁבַּעְתָּ לַאֲבֹתֵינוּ, אֶרֶץ זָבַת חָלָב וּדְבָשׁ:","cond":["taanit"]},{"kind":"instruction","text":"אם לא עלו כהנים לדוכן הש\"ץ אומר:","cond":["taanit"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, בָּרְכֵנוּ בַּבְּרָכָה הַמְשֻׁלֶּשֶׁת בַּתּוֹרָה הַכְּתוּבָה עַל יְדֵי מֹשֶׁה עַבְדֶּךָ, הָאֲמוּרָה מִפִּי אַהֲרֹן וּבָנָיו כֹּהֲנִים עַם קְדוֹשֶׁךָ, כָּאָמוּר: יְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ: יָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ: יִשָּׂא יהוה פָּנָיו אֵלֶיךָ וְיָשֵׂם לְךָ שָׁלוֹם:","cond":["taanit"]},{"kind":"text","text":"שִׂים שָׁלוֹם טוֹבָה וּבְרָכָה, חַיִּים חֵן וָחֶסֶד וְרַחֲמִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל עַמֶּךָ. בָּרְכֵנוּ אָבִינוּ כֻּלָּנוּ כְּאֶחָד (יַחַד) בְּאוֹר פָּנֶיךָ, כִּי בְאוֹר פָּנֶיךָ נָתַתָּ לָּנוּ יהוה אֱלֹהֵינוּ תּוֹרַת חַיִּים וְאַהֲבַת חֶסֶד, וּצְדָקָה וּבְרָכָה וְרַחֲמִים וְחַיִּים וְשָׁלוֹם. וְטוֹב יִהְיֶה בְעֵינֶיךָ לְבָרְכֵנוּ וּלְבָרֵךְ אֶת כָּל עַמְּךָ יִשְׂרָאֵל בְּכָל עֵת וּבְכָל שָׁעָה בִּשְׁלוֹמֶךָ (בְּרֹב עֹז וְשָׁלוֹם).","cond":[]},{"kind":"special","text":"בְּסֵפֶר חַיִּים, בְּרָכָה וְשָׁלוֹם, וּפַרְנָסָה טוֹבָה, וּגְזֵרוֹת טוֹבוֹת, יְשׁוּעוֹת וְנֶחָמוֹת, נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ, אֲנַחְנוּ וְכָל עַמְּךָ בֵּית יִשְׂרָאֵל, לְחַיִּים טוֹבִים וּלְשָׁלוֹם.","cond":["ayt"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הַמְבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם.","cond":[]},{"kind":"text","text":"יִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:","cond":[]},{"kind":"header","text":"תחנון","cond":["minchaTachanun"]},{"kind":"instruction","text":"יש נוהגים שלא לומר תחנון היום, ובפרט בארץ ישראל שיכולים בקלות להגיע לירושלים לשמוח עימם בשמחת פורים דמוקפין.","cond":["minchaTachanun","purim_meshulash_tachanun_message"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, תָּבוֹא לְפָנֶיךָ תְּפִלָּתֵנוּ וְאַל תִּתְעַלַּם מִתְּחִנָּתֵנוּ, שֶׁאֵין אָנוּ עַזֵּי פָנִים וּקְשֵׁי עֹרֶף לוֹמַר לְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ צַדִּיקִים אֲנַחְנוּ וְלֹא חָטָאנוּ, אֲבָל אֲנַחְנוּ וַאֲבוֹתֵינוּ חָטָאנוּ.\nאָשַׁמְנוּ, בָּגַדְנוּ, גָּזַלְנוּ, דִּבַּרְנוּ דֹפִי. הֶעֱוִינוּ, וְהִרְשַׁעְנוּ, זַדְנוּ, חָמַסְנוּ, טָפַלְנוּ שֶׁקֶר. יָעַצְנוּ רָע, כִּזַּבְנוּ, לַצְנוּ, מָרַדְנוּ, נִאַצְנוּ, סָרַרְנוּ, עָוִינוּ, פָּשַׁעְנוּ, צָרַרְנוּ, קִשִּׁינוּ עֹרֶף. רָשַׁעְנוּ, שִׁחַתְנוּ, תִּעַבְנוּ, תָּעִינוּ, תִּעְתַּעְנוּ.\nסַרְנוּ מִמִּצְוׂתֶיךָ וּמִמִּשְׁפָּטֶיךָ הַטּוֹבִים וְלֹא שָׁוָה-לָנוּ. וְאַתָּה צַדִּיק עַל כָּל הַבָּא עָלֵינוּ, כִּי אֱמֶת עָשִׂיתָ, וַאֲנַחְנוּ הִרְשָׁעְנוּ:","cond":["minchaTachanun"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["minchaTachanun"]},{"kind":"text","text":"אֵל אֶרֶךְ אַפַּיִם אַתָּה וּבַעַל הָרַחֲמִים נִקְרֵאתָ, וְדֶרֶךְ תְּשׁוּבָה הוֹרֵיתָ, גְּדֻלַּת רַחֲמֶיךָ וַחֲסָדֶיךָ תִּזְכֹּר הַיּוֹם וּבְכָל יוֹם לְזֶרַע יְדִידֶיךָ. תֵּפֶן אֵלֵינוּ בְּרַחֲמִים, כִּי אַתָּה הוּא בַּעַל הָרַחֲמִים. בְּתַחֲנוּן וּבִתְפִלָּה פָּנֶיךָ נְקַדֵּם, כְּהוֹדַעתָּ לֶעָנָו מִקֶּדֶם. מֵחֲרוֹן אַפְּךָ שׁוּב, כְּמוֹ בְּתוֹרָתְךָ כָּתוּב. וּבְצֵל כְּנָפֶיךָ נֶחְסֶה וְנִתְלוֹנָן, כְּיוֹם וַיֵּרֶד יהוה בֶּעָנָן. תַּעֲבֹר עַל פֶּשַׁע וְתִמְחֶה אָשָׁם, כְּיוֹם וַיִּתְיַצֵּב עִמּוֹ שָׁם. תַּאֲזִין שַׁוְעָתֵנוּ וְתַקְשִׁיב מֶנּוּ מַאֲמָר, כְּיוֹם וַיִּקְרָא בְשֵׁם יהוה, וְשָׁם נֶאֲמַר:\n\nוַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לַאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["minchaTachanun"]},{"kind":"instruction","text":"נפילת אפיים","cond":["minchaTachanun"]},{"kind":"text","text":"וַיֹּאמֶר דָּוִד אֶל גָּד, צַר לִי מְאֹד, נִפְּלָה נָּא בְיַד יהוה כִּי רַבִּים רַחֲמָיו, וּבְיַד אָדָם אַל אֶפֹּלָה:\n\nרַחוּם וְחַנּוּן חָטָאתִי לְפָנֶיך. יהוה מָלֵא רַחֲמִים, רַחֵם עָלַי וְקַבֵּל תַּחֲנוּנָי.\n\nיהוה, אַל בְּאַפְּךָ תוֹכִיחֵנִי וְאַל בַּחֲמָתְךָ תְיַסְּרֵנִי: חָנֵּנִי יהוה כִּי אֻמְלַל אָנִי, רְפָאֵנִי יהוה כִּי נִבְהֲלוּ עֲצָמָי: וְנַפְשִׁי נִבְהֲלָה מְאֹד, וְאַתָּה יהוה עַד מָתָי: שׁוּבָה יהוה חַלְּצָה נַפְשִׁי, הוֹשִׁיעֵנִי לְמַעַן חַסְדֶּךָ: כִּי אֵין בַּמָּוֶת זִכְרֶךָ, בִּשְׁאוֹל מִי יוֹדֶה לָּךְ: יָגַעְתִּי בְאַנְחָתִי, אַשְׂחֶה בְכָל לַיְלָה מִטָּתִי, בְּדִמְעָתִי עַרְשִׂי אַמְסֶה: עָשְׁשָׁה מִכַּעַס עֵינִי, עָתְקָה בְּכָל צוֹרְרָי: סוּרוּ מִמֶּנִּי כָּל פֹּעֲלֵי אָוֶן כִּי שָׁמַע יהוה קוֹל בִּכְיִי: שָׁמַע יהוה תְּחִנָּתִי, יהוה תְּפִלָּתִי יִקָּח: יֵבֹשׁוּ וְיִבָּהֲלוּ מְאֹד כָּל אֹיְבָי, יָשֻׁבוּ יֵבֹשׁוּ רָגַע:","cond":["minchaTachanun"]},{"kind":"header","text":"אבינו מלכנו","cond":["minchaTachanun","noGedalya"]},{"kind":"instruction","text":"אבינו מלכנו","cond":["minchaTachanun","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חָטָאנוּ לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, אֵין לָנוּ מֶלֶךְ אֶלָּא אָתָּה.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה עִמָּנוּ לְמַעַן שְׁמֶךָ.","cond":["minchaTachanun","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חַדֵּשׁ עָלֵינוּ שָׁנָה טוֹבָה.","cond":["minchaTachanun","noGedalya","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, בָּרֵךְ עָלֵינוּ שָׁנָה טוֹבָה.","cond":["minchaTachanun","noGedalya","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, בַּטֵּל מֵעָלֵינוּ כָּל גְּזֵרוֹת קָשׁוֹת.\nאָבִינוּ מַלְכֵּנוּ, בַּטֵּל מַחְשְׁבוֹת שׂוֹנְאֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, הָפֵר עֲצַת אוֹיְבֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה כָּל צַר וּמַשְׂטִין מֵעָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, סְתֹם פִּיּוֹת מַשְׂטִינֵינוּ וּמְקַטְרְגֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה דֶבֶר וְחֶרֶב וְרָעָב וּשְׁבִי וּמַשְׁחִית וְעָוׂן וּשְׁמַד מִבְּנֵי בְרִיתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, מְנַע מַגֵּפָה מִנַּחֲלָתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, סְלַח וּמְחַל לְכָל עֲוׂנוֹתֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, מְחֵה וְהַעֲבֵר פְּשָׁעֵינוּ וְחַטֹּאתֵינוּ מִנֶּגֶד עֵינֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, מְחֹק בְּרַחֲמֶיךָ הָרַבִּים כָּל שִׁטְרֵי חוֹבוֹתֵינוּ.","cond":["minchaTachanun","noGedalya"]},{"kind":"instruction","text":"מכאן אומרים בקול עם החזן","cond":["minchaTachanun","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, הַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, שְׁלַח רְפוּאָה שְׁלֵמָה לְחוֹלֵי עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, קְרַע רֹע גְּזַר דִּינֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ בְּזִכְרוֹן טוֹב לְפָנֶיךָ.","cond":["minchaTachanun","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר חַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר גְּאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר פַּרְנָסָה וְכַלְכָּלָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר זְכֻיּוֹת.\nאָבִינוּ מַלְכֵּנוּ, כָָּתְבֵנוּ בְּסֵפֶר סְלִיחָה וּמְחִילָה.","cond":["minchaTachanun","noGedalya","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לְחַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִגְאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לְפַרְנָסָה וְכַלְכָּלָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִזְכֻיּוֹת.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִסְלִיחָה וּמְחִילָה.","cond":["minchaTachanun","noGedalya","noGedalya"]},{"kind":"instruction","text":"עד כאן עם החזן","cond":["minchaTachanun","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, הַצְמַח לָנוּ יְשׁוּעָה בְּקָרוֹב.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן יִשְׂרָאֵל עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן מְשִׁיחֶךָ.\nאָבִינוּ מַלְכֵּנוּ, מַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, מַלֵּא אֲסָמֵינוּ שָׂבָע.\nאָבִינוּ מַלְכֵּנוּ, שְׁמַע קוֹלֵנוּ, חוּס וְרַחֵם עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, קַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, פְּתַח שַׁעֲרֵי שָׁמַיִם לִתְפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, זְכֹר כִּי עָפָר אֲנַחְנוּ.\nאָבִינוּ מַלְכֵּנוּ, נָא אַל תְּשִׁיבֵנוּ רֵיקָם מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, תְּהֵא הַשָּׁעָה הַזֹּאת שְׁעַת רַחֲמִים וְעֵת רָצוֹן מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, חֲמֹל עָלֵינוּ וְעַל עוֹלָלֵינוּ וְטַפֵּנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן הֲרוּגִים עַל שֶׁם קָדְשֶׁךָ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן טְבוּחִים עַל יִחוּדֶךָ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן בָּאֵי בָאֵשׁ וּבַמָּיִּם עַל קִדּוּשׁ שְׁמֶךָ.\nאָבִינוּ מַלְכֵּנוּ, נְקֹם נִקְמַת דַּם עֲבָדֶיךָ הַשָּׁפוּךְ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַנְךָ אִם לֹא לְמַעַנֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַנְךָ וְהוֹשִׁיעֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַן רַחֲמֶיךָ הָרַבִּים.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַן שִׁמְךָ הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא שֶׁנִּקְרָא עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, חָנֵּנוּ וַעֲנֵנוּ כִּי אֵין בָּנוּ מַעֲשִׂים, עֲשֵׂה עִמָּנוּ צְדָקָה וָחֶסֶד וְהוֹשִׁיעֵנוּ.","cond":["minchaTachanun","noGedalya"]},{"kind":"header","text":"אבינו מלכנו","cond":["minchaTachanun","ayt"]},{"kind":"instruction","text":"אבינו מלכנו","cond":["minchaTachanun","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חָטָאנוּ לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, אֵין לָנוּ מֶלֶךְ אֶלָּא אָתָּה.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה עִמָּנוּ לְמַעַן שְׁמֶךָ.","cond":["minchaTachanun","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חַדֵּשׁ עָלֵינוּ שָׁנָה טוֹבָה.","cond":["minchaTachanun","ayt","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, בָּרֵךְ עָלֵינוּ שָׁנָה טוֹבָה.","cond":["minchaTachanun","ayt","noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, בַּטֵּל מֵעָלֵינוּ כָּל גְּזֵרוֹת קָשׁוֹת.\nאָבִינוּ מַלְכֵּנוּ, בַּטֵּל מַחְשְׁבוֹת שׂוֹנְאֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, הָפֵר עֲצַת אוֹיְבֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה כָּל צַר וּמַשְׂטִין מֵעָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, סְתֹם פִּיּוֹת מַשְׂטִינֵינוּ וּמְקַטְרְגֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה דֶבֶר וְחֶרֶב וְרָעָב וּשְׁבִי וּמַשְׁחִית וְעָוׂן וּשְׁמַד מִבְּנֵי בְרִיתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, מְנַע מַגֵּפָה מִנַּחֲלָתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, סְלַח וּמְחַל לְכָל עֲוׂנוֹתֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, מְחֵה וְהַעֲבֵר פְּשָׁעֵינוּ וְחַטֹּאתֵינוּ מִנֶּגֶד עֵינֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, מְחֹק בְּרַחֲמֶיךָ הָרַבִּים כָּל שִׁטְרֵי חוֹבוֹתֵינוּ.","cond":["minchaTachanun","ayt"]},{"kind":"instruction","text":"מכאן אומרים בקול עם החזן","cond":["minchaTachanun","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, הַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, שְׁלַח רְפוּאָה שְׁלֵמָה לְחוֹלֵי עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, קְרַע רֹע גְּזַר דִּינֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ בְּזִכְרוֹן טוֹב לְפָנֶיךָ.","cond":["minchaTachanun","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר חַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר גְּאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר פַּרְנָסָה וְכַלְכָּלָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר זְכֻיּוֹת.\nאָבִינוּ מַלְכֵּנוּ, כָָּתְבֵנוּ בְּסֵפֶר סְלִיחָה וּמְחִילָה.","cond":["minchaTachanun","ayt","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לְחַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִגְאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לְפַרְנָסָה וְכַלְכָּלָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִזְכֻיּוֹת.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִסְלִיחָה וּמְחִילָה.","cond":["minchaTachanun","ayt","noGedalya"]},{"kind":"instruction","text":"עד כאן עם החזן","cond":["minchaTachanun","ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, הַצְמַח לָנוּ יְשׁוּעָה בְּקָרוֹב.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן יִשְׂרָאֵל עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן מְשִׁיחֶךָ.\nאָבִינוּ מַלְכֵּנוּ, מַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, מַלֵּא אֲסָמֵינוּ שָׂבָע.\nאָבִינוּ מַלְכֵּנוּ, שְׁמַע קוֹלֵנוּ, חוּס וְרַחֵם עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, קַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, פְּתַח שַׁעֲרֵי שָׁמַיִם לִתְפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, זְכֹר כִּי עָפָר אֲנַחְנוּ.\nאָבִינוּ מַלְכֵּנוּ, נָא אַל תְּשִׁיבֵנוּ רֵיקָם מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, תְּהֵא הַשָּׁעָה הַזֹּאת שְׁעַת רַחֲמִים וְעֵת רָצוֹן מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, חֲמֹל עָלֵינוּ וְעַל עוֹלָלֵינוּ וְטַפֵּנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן הֲרוּגִים עַל שֶׁם קָדְשֶׁךָ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן טְבוּחִים עַל יִחוּדֶךָ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן בָּאֵי בָאֵשׁ וּבַמָּיִּם עַל קִדּוּשׁ שְׁמֶךָ.\nאָבִינוּ מַלְכֵּנוּ, נְקֹם נִקְמַת דַּם עֲבָדֶיךָ הַשָּׁפוּךְ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַנְךָ אִם לֹא לְמַעַנֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַנְךָ וְהוֹשִׁיעֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַן רַחֲמֶיךָ הָרַבִּים.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַן שִׁמְךָ הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא שֶׁנִּקְרָא עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, חָנֵּנוּ וַעֲנֵנוּ כִּי אֵין בָּנוּ מַעֲשִׂים, עֲשֵׂה עִמָּנוּ צְדָקָה וָחֶסֶד וְהוֹשִׁיעֵנוּ.","cond":["minchaTachanun","ayt"]},{"kind":"instruction","text":"שומר ישראל","cond":["minchaTachanun"]},{"kind":"text","text":"שׁוֹמֵר יִשְׂרָאֵל, שְׁמֹר שְׁאֵרִית יִשְׂרָאֵל, וְאַל יֹאבַד יִשְׂרָאֵל, הָאוֹמְרִים שְׁמַע יִשְׂרָאֵל.\nשׁוֹמֵר גּוֹי אֶחָד, שְׁמֹר שְׁאֵרִית עַם אֶחָד, וְאַל יֹאבַד גּוֹי אֶחָד, הַמְיַחֲדִים שִׁמְךָ יהוה אֱלֹהֵינוּ יהוה אֶחָד.\nשׁוֹמֵר גּוֹי קָדוֹשׁ, שְׁמֹר שְׁאֵרִית עַם קָדוֹשׁ, וְאַל יֹאבַד גּוֹי קָדוֹשׁ, הַמְשַׁלְּשִׁים בְּשָׁלֹשׁ קְדֻשּׁוֹת לְקָדוֹשׁ.\n\nמִתְרַצֶּה בְּרַחֲמִים וּמִתְפַּיֵּס בְּתַחֲנוּנִים, הִתְרַצֶּה וְהִתְפַּיֵּס לְדוֹר עָנִי. כִּי אֵין עוֹזֵר.\nאָבִינוּ מַלְכֵּנוּ. חָנֵּנוּ וַעֲנֵנוּ, כִּי אֵין בָּנוּ מַעֲשִׂים, עֲשֵׂה עִמָּנוּ צְדָקָה וָחֶסֶד וְהוֹשִׁיעֵנוּ.\n\nוַאֲנַחְנוּ לֹא נֵדַע מַה נַּעֲשֶׂה, כִּי עָלֶיךָ עֵינֵינוּ: זְכֹר רַחֲמֶיךָ יהוה וַחֲסָדֶיךָ, כִּי מֵעוֹלָם הֵמָּה: יְהִי חַסְדְּךָ יהוה עָלֵינוּ, כַּאֲשֶׁר יִחַלְנוּ לָךְ: אַל תִּזְכָּר לָנוּ עֲוׂנוֹת רִאשׁוֹנִים, מַהֵר יְקַדְּמוּנוּ רַחֲמֶיךָ, כִּי דַלּוֹנוּ מְאֹד: עֶזְרֵנוּ בְּשֵׁם יהוה, עֹשֶׂה שָׁמַיִם וָאָרֶץ: חָנֵּנוּ יהוה חָנֵּנוּ, כִּי רַב שָׂבַעְנוּ בוּז: בְּרֹגֶז רַחֵם תִּזְכּוֹר: בְּרֹגֶז עֲקֵדָה תִזְכֹּר, בְּרֹגֶז תְּמִימוּת תִזְכֹּר. יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ: כִּי הוּא יָדַע יִצְרֵנוּ, זָכוּר כִּי עָפָר אֲנָחְנוּ: עָזְרֵנוּ אֱלֹהֵי יִשְׁעֵנוּ עַל דְּבַר כְּבוֹד שְׁמֶךָ, וְהַצִּילֵנוּ וְכַפֵּר עַל חַטֹּאתֵינוּ לְמַעַן שְׁמֶךָ:","cond":["minchaTachanun"]},{"kind":"instruction","text":"קדיש תתקבל","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":[]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"תִּתְקַבַּל צְלוֹתְהוֹן וּבָעוּתְהוֹן דְּכָל בֵּית יִשְׂרָאֵל קֳדָם אֲבוּהוֹן דִּי בִשְׁמַיָּא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"header","text":"עלינו לשבח","cond":[]},{"kind":"text","text":"עָלֵינוּ לְשַׁבֵּחַ לַאֲדוֹן הַכֹּל, לָתֵת גְּדֻלָּה לְיוֹצֵר בְּרֵאשִׁית, שֶׁלֹּא עָשָׂנוּ כְּגוֹיֵי הָאֲרָצוֹת, וְלֹא שָׂמָנוּ כְּמִשְׁפְּחוֹת הָאֲדָמָה. שֶׁלֹּא שָׂם חֶלְקֵנוּ כָּהֶם, וְגוֹרָלֵנוּ כְּכָל-הֲמוֹנָם[, שֶׁהֵם מִשְׁתַּחֲוִים לְהֶבֶל וָרִיק, וּמִתְפַּלְּלִים אֶל אֵל לֹא יוֹשִׁיעַ]. וַאֲנַחְנוּ כּוֹרְעִים וּמִשְׁתַּחֲוִים וּמוֹדִים לִפְנֵי מֶלֶךְ מַלְכֵי הַמְּלָכִים הַקָּדוֹשׁ בָּרוּךְ הוּא, שֶׁהוּא נוֹטֶה שָׁמַיִם וְיוֹסֵד אָרֶץ, וּמוֹשַׁב יְקָרוֹ בַּשָּׁמַיִם מִמַּעַל, וּשְׁכִינַת עֻזּוֹ בְּגָבְהֵי מְרוֹמִים. הוּא אֱלֹהֵינוּ, אֵין עוֹד, אֱמֶת מַלְכֵּנוּ, אֶפֶס זוּלָתוֹ. כַּכָּתוּב בְּתוֹרָתוֹ: וְיָדַעְתָּ הַיּוֹם וַהֲשֵׁבֹתָ אֶל לְבָבֶךָ כִּי יהוה הוּא הָאֱלֹהִים בַּשָּׁמַיִם מִמַּעַל וְעַל הָאָרֶץ מִתָּחַת אֵין עוֹד:","cond":[]},{"kind":"text","text":"וְעַל כֵּן נְקַוֶּה לְךָ יהוה אֱלֹהֵינוּ, לִרְאוֹת מְהֵרָה בְּתִפְאֶרֶת עֻזֶּךָ, לְהַעֲבִיר גִּלּוּלִים מִן הָאָרֶץ, וְהָאֱלִילִים כָּרוֹת יִכָּרֵתוּן, לְתַקֵּן עוֹלָם בְּמַלְכוּת שַׁדַּי, וְכָל בְּנֵי בָשָׂר יִקְרְאוּ בִשְׁמֶךָ, לְהַפְנוֹת אֵלֶיךָ כָּל רִשְׁעֵי אָרֶץ. יַכִּירוּ וְיֵדְעוּ כָּל יוֹשְׁבֵי תֵבֵל, כִּי לְךָ תִכְרַע כָּל בֶּרֶךְ, תִּשָּׁבַע כָּל לָשׁוֹן. לְפָנֶיךָ יהוה אֱלֹהֵינוּ יִכְרְעוּ וְיִפֹּלוּ, וְלִכְבוֹד שִׁמְךָ יְקָר יִתֵּנוּ, וִיקַבְּלוּ כֻלָּם אֶת עֹל מַלְכוּתֶךָ, וְתִמְלֹךְ עֲלֵיהֶם מְהֵרָה לְעוֹלָם וָעֶד. כִּי הַמַּלְכוּת שֶׁלְּךָ הִיא, וּלְעוֹלְמֵי עַד תִּמְלֹךְ בְּכָבוֹד. כַּכָּתוּב בְּתוֹרָתֶךָ: יהוה יִמְלֹךְ לְעֹלָם וָעֶד: וְנֶאֱמַר: וְהָיָה יהוה לְמֶלֶךְ עַל כָּל הָאָרֶץ, בַּיּוֹם הַהוּא יִהְיֶה יהוה אֶחָד וּשְׁמוֹ אֶחָד:","cond":[]},{"kind":"text","text":"אַל תִּירָא מִפַּחַד פִּתְאֹם וּמִשֹּׁאַת רְשָׁעִים כִּי תָבֹא: עֻצוּ עֵצָה וְתֻפָר, דַּבְּרוּ דָבָר וְלֹא יָקוּם, כִּי עִמָּנוּ אֵל: וְעַד זִקְנָה אֲנִי הוּא, וְעַד שֵׂיבָה אֲנִי אֶסְבֹּל אֲנִי עָשִׂיתִי וַאֲנִי אֶשָּׂא וַאֲנִי אֶסְבֹּל וַאֲמַלֵּט:","cond":[]},{"kind":"instruction","text":"קדיש יתום","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":[]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"header","text":"השלמת שחרית","cond":["tishaaBeav"]},{"kind":"header","text":"שיר של יום","cond":["tishaaBeav"]},{"kind":"instruction","text":"שיר של יום","cond":["tishaaBeav"]},{"kind":"text","text":"תְּפִלָּה לְדָוִד, הַטֵּה יהוה אָזְנְךָ עֲנֵנִי, כִּי עָנִי וְאֶבְיוֹן אָנִי: שָׁמְרָה נַפְשִׁי כִּי חָסִיד אָנִי, הוֹשַׁע עַבְדְּךָ, אַתָּה אֱלֹהַי, הַבּוֹטֵחַ אֵלֶיךָ: חָנֵּנִי אֲדֹנָי, כִּי אֵלֶיךָ אֶקְרָא כָּל הַיּוֹם: שַׂמֵּחַ נֶפֶשׁ עַבְדֶּךָ, כִּי אֵלֶיךָ אֲדֹנָי נַפְשִׁי אֶשָּׂא: כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ: הַאֲזִינָה יהוה תְּפִלָּתִי וְהַקְשִׁיבָה בְּקוֹל תַּחֲנוּנוֹתָי: בְּיוֹם צָרָתִי אֶקְרָאֶךָּ כִּי תַעֲנֵנִי: אֵין כָּמוֹךָ בָאֱלֹהִים, אֲדֹנָי, וְאֵין כְּמַעֲשֶׂיךָ: כָּל גּוֹיִם אֲשֶׁר עָשִׂיתָ יָבוֹאוּ וְיִשְׁתַּחֲווּ לְפָנֶיךָ, אֲדֹנָי, וִיכַבְּדוּ לִשְׁמֶךָ: כִּי גָדוֹל אַתָּה וְעֹשֵׂה נִפְלָאוֹת, אַתָּה אֱלֹהִים לְבַדֶּךָ: הוֹרֵנִי יהוה דַּרְכֶּךָ, אֲהַלֵּךְ בַּאֲמִתֶּךָ, יַחֵד לְבָבִי לְיִרְאָה שְׁמֶךָ: אוֹדְךָ אֲדֹנָי אֱלֹהַי בְּכָל לְבָבִי, וַאֲכַבְּדָה שִׁמְךָ לְעוֹלָם: כִּי חַסְדְּךָ גָּדוֹל עָלָי, וְהִצַּלְתָּ נַפְשִׁי מִשְּׁאוֹל תַּחְתִּיָּה: אֱלֹהִים, זֵדִים קָמוּ עָלַי, וַעֲדַת עָרִיצִים בִּקְשׁוּ נַפְשִׁי, וְלֹא שָׂמוּךָ לְנֶגְדָּם: וְאַתָּה אֲדֹנָי אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב חֶסֶד וֶאֱמֶת: פְּנֵה אֵלַי וְחָנֵּנִי, תְּנָה עֻזְּךָ לְעַבְדֶּךָ, וְהוֹשִׁיעָה לְבֶן אֲמָתֶךָ: עֲשֵׂה עִמִּי אוֹת לְטוֹבָה, וְיִרְאוּ שֹׂנְאַי וְיֵבֹשׁוּ, כִּי אַתָּה יהוה עֲזַרְתַּנִי וְנִחַמְתָּנִי:","cond":["tishaaBeav","shacharitTachanun"]},{"kind":"text","text":"בֵּית יַעֲקֹב, לְכוּ וְנֵלְכָה בְּאוֹר יהוה: כִּי כָּל הָעַמִּים יֵלְכוּ אִישׁ בְּשֵׁם אֱלֹהָיו, וַאֲנַחְנוּ נֵלֵךְ בְּשֵׁם יהוה אֱלֹהֵינוּ לְעוֹלָם וָעֶד: יְהִי יהוה אֱלֹהֵינוּ עִמָּנוּ כַּאֲשֶׁר הָיָה עִם אבוֹתֵינוּ, אַל יַעַזְבֵנוּ וְאַל יִטְּשֵׁנוּ: לְהַטּות לְבָבֵנוּ אֵלָיו, לָלֶכֶת בְּכָל דְּרָכָיו וְלִשְׁמֹר מִצְוׂתָיו וְחֻקָּיו וּמִשְׁפָּטָיו אֲשֶׁר צִוָּה אֶת אֲבֹתֵינוּ: וְיִהְיוּ דְבָרַי אֵלֶּה אֲשֶׁר הִתְחַנַּנְתִּי לִפְנֵי יהוה קְרֹבִים אֶל יהוה אֱלֹהֵינוּ יוֹמָם וָלָיְלָה, לַעֲשׂוֹת מִשְׁפַּט עַבְדּוֹ וּמִשְׁפַּט עַמּוֹ יִשְׂרָאֵל דְּבַר יוֹם בְּיוֹמוֹ: לְמַעַן דַּעַת כָּל עַמֵּי הָאָרֶץ כִּי יהוה הוּא הָאֱלֹהִים, אֵין עוד:\n\nשִׁיר הַמַּעֲלוֹת לְדָוִד, לוּלֵי יהוה שֶׁהָיָה לָנוּ יֹאמַר נָא יִשְׂרָאֵל: לוּלֵי יהוה שֶׁהָיָה לָנוּ בְּקוּם עָלֵינוּ אָדָם: אֲזַי חַיִּים בְּלָעוּנוּ בַּחֲרוֹת אַפָּם בָּנוּ: אֲזַי הַמַּיִם שְׁטָפוּנוּ נַחְלָה עָבַר עַל נַפְשֵׁנוּ: אֲזַי עָבַר עַל נַפְשֵׁנוּ הַמַּיִם הַזֵּידוֹנִים: בָּרוּךְ יהוה שֶׁלֹּא נְתָנָנוּ טֶרֶף לְשִׁנֵּיהֶם: נַפְשֵׁנוּ כְּצִפּוֹר נִמְלְטָה מִפַּח יוֹקְשִׁים, הַפַּח נִשְׁבָּר וַאֲנַחְנוּ נִמְלָטְנוּ: עֶזְרֵנוּ בְּשֵׁם יהוה, עֹשֵׂה שָׁמַיִם וָאָרֶץ:","cond":["tishaaBeav","lamnatzeach"]},{"kind":"text","text":"הַיּוֹם יוֹם רִאשׁוֹן בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["tishaaBeav","sun"]},{"kind":"text","text":"לְדָוִד מִזְמוֹר, לַיהוה הָאָרֶץ וּמְלוֹאָהּ, תֵּבֵל וְיֹשְׁבֵי בָהּ: כִּי הוּא עַל יַמִּים יְסָדָהּ, וְעַל נְהָרוֹת יְכוֹנְנֶהָ: מִי יַעֲלֶה בְהַר יהוה, וּמִי יָקוּם בִּמְקוֹם קָדְשׁוֹ: נְקִי כַפַּיִם וּבַר לֵבָב, אֲשֶׁר לֹא נָשָׂא לַשָּׁוְא נַפְשִׁי וְלֹא נִשְׁבַּע לְמִרְמָה: יִשָּׂא בְרָכָה מֵאֵת יהוה, וּצְדָקָה מֵאֱלֹהֵי יִשְׁעוֹ: זֶה דּוֹר דֹּרְשָׁיו, מְבַקְשֵׁי פָנֶיךָ יַעֲקֹב סֶלָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וְהִנָּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבוֹא מֶלֶךְ הַכָּבוֹד: מִי זֶה מֶלֶךְ הַכָּבוֹד, יהוה עִזּוּז וְגִבּוֹר, יהוה גִּבּוֹר מִלְחָמָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבֹא מֶלֶךְ הַכָּבוֹד: מִי הוּא זֶה מֶלֶךְ הַכָּבוֹד, יהוה צְבָאוֹת הוּא מֶלֶךְ הַכָּבוֹד סֶלָה:","cond":["tishaaBeav","sun"]},{"kind":"text","text":"הַיּוֹם יוֹם שֵׁנִי בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["tishaaBeav","mon"]},{"kind":"text","text":"שִׁיר מִזְמוֹר לִבְנֵי קֹרַח: גָּדוֹל יהוה וּמְהֻלָּל מְאֹד בְּעִיר אֱלֹהֵינוּ הַר קָדְשׁוֹ: יְפֵה נוֹף, מְשׂוֹשׂ כָּל הָאָרֶץ, הַר צִיּוֹן יַרְכְּתֵי צָפוֹן קִרְיַת מֶלֶךְ רָב: אֱלֹהִים בְּאַרְמְנוֹתֶיהָ נוֹדַע לְמִשְׂגָּב: כִּי הִנֵּה הַמְּלָכִים נוֹעֲדוּ עָבְרוּ יַחְדָּו: הֵמָּה רָאוּ כֵּן תָּמָהוּ, נִבְהֲלוּ נֶחְפָּזוּ: רְעָדָה אֲחָזָתַם שָׁם, חִיל כַּיּוֹלֵדָה: בְּרוּחַ קָדִים תְּשַׁבֵּר אֳנִיּוֹת תַּרְשִׁישׁ: כַּאֲשֶׁר שָׁמַעְנוּ כֵּן רָאִינוּ בְּעִיר יהוה צְבָאוֹת בְּעִיר אֱלֹהֵינוּ, אֱלֹהִים יְכוֹנְנֶהָ עַד עוֹלָם סֶלָה: דִּמִּינוּ אֱלֹהִים חַסְדֶּךָ בְּקֶרֶב הֵיכָלֶךָ: כְּשִׁמְךָ אֱלֹהִים כֵּן תְּהִלָּתְךָ עַל קַצְוֵי אֶרֶץ, צֶדֶק מָלְאָה יְמִינֶךָ: יִשְׂמַח הַר צִיּוֹן, תָּגֵלְנָה בְּנוֹת יְהוּדָה, לְמַעַן מִשְׁפָּטֶיךָ: סֹבּוּ צִיּוֹן וְהַקִּיפוּהָ, סִפְרוּ מִגְדָּלֶיהָ: שִׁיתוּ לִבְּכֶם לְחֵילָה, פַּסְּגוּ אַרְמְנוֹתֶיהָ, לְמַעַן תְּסַפְּרוּ לְדוֹר אַחֲרוֹן: כִּי זֶה אֱלֹהִים אֱלֹהֵינוּ עוֹלָם וָעֶד, הוּא יְנַהֲגֵנוּ עַל מוּת:","cond":["tishaaBeav","mon"]},{"kind":"text","text":"הַיּוֹם יוֹם שְׁלִישִׁי בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["tishaaBeav","tue"]},{"kind":"text","text":"מִזְמוֹר לְאָסָף, אֱלֹהִים נִצָּב בַּעֲדַת אֵל, בְּקֶרֶב אֱלֹהִים יִשְׁפֹּט: עַד מָתַי תִּשְׁפְּטוּ עָוֶל וּפְנֵי רְשָׁעִים תִּשְׂאוּ סֶלָה: שִׁפְטוּ דַל וְיָתוֹם, עָנִי וָרָשׁ הַצְדִּיקוּ: פַּלְּטוּ דַל וְאֶבְיוֹן, מִיַּד רְשָׁעִים הַצִּילוּ: לֹא יָדְעוּ וְלֹא יָבִינוּ, בַּחֲשֵׁכָה יִתְהַלָּכוּ, יִמּוֹטוּ כָּל מוֹסְדֵי אָרֶץ: אֲנִי אָמַרְתִּי אֱלֹהִים אַתֶּם וּבְנֵי עֶלְיוֹן כֻּלְּכֶם: אָכֵן כְּאָדָם תְּמוּתוּן וּכְאַחַד הַשָּׂרִים תִּפֹּלוּ: קוּמָה אֱלֹהִים שָׁפְטָה הָאָרֶץ, כִּי אַתָּה תִנְחַל בְּכָל הַגּוֹיִם:","cond":["tishaaBeav","tue"]},{"kind":"text","text":"הַיּוֹם יוֹם רְבִיעִי בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["tishaaBeav","wed"]},{"kind":"text","text":"אֵל נְקָמוֹת יהוה, אֵל נְקָמוֹת הוֹפִיעַ: הִנָּשֵׂא שֹׁפֵט הָאָרֶץ, הָשֵׁב גְּמוּל עַל גֵּאִים: עַד מָתַי רְשָׁעִים, יהוה, עַד מָתַי רְשָׁעִים יַעֲלֹזוּ: יַבִּיעוּ יְדַבְּרוּ עָתָק, יִתְאַמְּרוּ כָּל פֹעֲלֵי אָוֶן: עַמְּךָ יהוה יְדַכְּאוּ, וְנַחֲלָתְךָ יְעַנּוּ: אַלְמָנָה וְגֵר יַהֲרֹגוּ, וִיתוֹמִים יְרַצֵּחוּ: וַיֹּאמְרוּ לֹא יִרְאֶה יָהּ, וְלֹא יָבִין אֱלֹהֵי יַעֲקֹב: בִּינוּ בֹּעֲרִים בָּעָם, וּכְסִילִים מָתַי תַּשְׂכִּילוּ: הַנֹּטַע אֹזֶן הֲלֹא יִשְׁמָע, אִם יֹצֵר עַיִן הֲלֹא יַבִּיט: הֲיֹסֵר גּוֹיִם הֲלֹא יוֹכִיחַ, הַמְלַמֵּד אָדָם דָּעַת: יהוה יֹדֵעַ מַחְשְׁבוֹת אָדָם כִּי הֵמָּה הָבֶל: אַשְׁרֵי הַגֶּבֶר אֲשֶׁר תְּיַסְּרֶנּוּ יָּהּ, וּמִתּוֹרָתְךָ תְלַמְּדֶנּוּ: לְהַשְׁקִיט לוֹ מִימֵי רָע, עַד יִכָּרֶה לָרָשָׁע שָׁחַת: כִּי לֹא יִטֹּשׁ יהוה עַמּוֹ, וְנַחֲלָתוֹ לֹא יַעֲזֹב: כִּי עַד צֶדֶק יָשׁוּב מִשְׁפָּט, וְאַחֲרָיו כָּל יִשְׁרֵי לֵב: מִי יָקוּם לִי עִם מְרֵעִים, מִי יִתְיַצֵּב לִי עִם פֹּעֲלֵי אָוֶן: לוּלֵי יהוה עֶזְרָתָה לִּי, כִּמְעַט שָׁכְנָה דוּמָה נַפְשִׁי: אִם אָמַרְתִּי מָטָה רַגְלִי, חַסְדְּךָ יהוה יִסְעָדֵנִי: בְּרֹב שַׂרְעַפַּי בְּקִרְבִּי, תַּנְחוּמֶיךָ יְשַׁעַשְׁעוּ נַפְשִׁי: הַיְחָבְרְךָ כִּסֵּא הַוּוֹת, יֹצֵר עָמָל עֲלֵי חֹק: יָגוֹדּוּ עַל נֶפֶשׁ צַדִּיק, וְדָם נָקִי יַרְשִׁיעוּ: וַיְהִי יהוה לִי לְמִשְׂגָּב, וֵאלֹהַי לְצוּר מַחְסִי: וַיָּשֶׁב עֲלֵיהֶם אֶת אוֹנָם וּבְרָעָתָם יַצְמִיתֵם, יַצְמִיתֵם יהוה אֱלֹהֵינוּ:\nלְכוּ נְרַנְּנָה לַיהוה, נָרִיעָה לְצוּר יִשְׁעֵנוּ: נְקַדְּמָה פָנָיו בְּתוֹדָה, בִּזְמִרוֹת נָרִיעַ לוֹ: כִּי אֵל גָּדוֹל יהוה, וּמֶלֶךְ גָּדוֹל עַל כָּל אֱלֹהִים:","cond":["tishaaBeav","wed"]},{"kind":"text","text":"הַיּוֹם יוֹם חֲמִישִׁי בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["tishaaBeav","thu"]},{"kind":"text","text":"לַמְנַצֵּחַ עַל הַגִּתִּית לְאָסָף: הַרְנִינוּ לֵאלֹהִים עֻזֵּנוּ, הָרִיעוּ לֵאלֹהֵי יַעֲקֹב: שְׂאוּ זִמְרָה וּתְנוּ תֹף, כִּנּוֹר נָעִים עִם נָבֶל: תִּקְעוּ בַחֹדֶשׁ שׁוֹפָר, בַּכֵּסֶה לְיוֹם חַגֵּנוּ: כִּי חֹק לְיִשְׂרָאֵל הוּא, מִשְׁפָּט לֵאלֹהֵי יַעֲקֹב: עֵדוּת בִּיהוֹסֵף שָׂמוֹ בְּצֵאתוֹ עַל אֶרֶץ מִצְרָיִם, שְׂפַת לֹא יָדַעְתִּי אֶשְׁמָע: הֲסִירוֹתִי מִסֵּבֶל שִׁכְמוֹ, כַּפָּיו מִדּוּד תַּעֲבֹרְנָה: בַּצָּרָה קָרָאתָ וָאֲחַלְּצֶךָּ, אֶעֶנְךָ בְּסֵתֶר רַעַם, אֶבְחָנְךָ עַל מֵי מְרִיבָה סֶלָה: שְׁמַע עַמִּי וְאָעִידָה בָּךְ, יִשְׂרָאֵל אִם תִּשְׁמַע לִי: לֹא יִהְיֶה בְךָ אֵל זָר, וְלֹא תִשְׁתַּחֲוֶה לְאֵל נֵכָר: אָנֹכִי יהוה אֱלֹהֶיךָ הַמַּעַלְךָ מֵאֶרֶץ מִצְרָיִם, הַרְחֶב פִּיךָ וַאֲמַלְאֵהוּ: וְלֹא שָׁמַע עַמִּי לְקוֹלִי, וְיִשְׂרָאֵל לֹא אָבָה לִי: וָאֲשַׁלְּחֵהוּ בִּשְׁרִירוּת לִבָּם, יֵלְכוּ בְּמוֹעֲצוֹתֵיהֶם: לוּ עַמִּי שֹׁמֵעַ לִי, יִשְׂרָאֵל בִּדְרָכַי יְהַלֵּכוּ: כִּמְעַט אוֹיְבֵיהֶם אַכְנִיעַ, וְעַל צָרֵיהֶם אָשִׁיב יָדִי: מְשַׂנְאֵי יהוה יְכַחֲשׁוּ לוֹ, וִיהִי עִתָּם לְעוֹלָם: וַיַּאֲכִילֵהוּ מֵחֵלֶב חִטָּה, וּמִצּוּר, דְּבַשׁ אַשְׂבִּיעֶךָ:","cond":["tishaaBeav","thu"]},{"kind":"text","text":"הַיּוֹם יוֹם שִׁשִּׁי בְּשַׁבָּת, שֶׁבּוֹ הָיוּ הַלְוִיִּם אוֹמְרִים בְּבֵית הַמִּקְדָּשׁ:","cond":["tishaaBeav","fri"]},{"kind":"text","text":"יהוה מָלָךְ גֵּאוּת לָבֵשׁ, לָבֵשׁ יהוה עֹז הִתְאַזָּר, אַף תִּכּוֹן תֵּבֵל בַּל תִּמּוֹט: נָכוֹן כִּסְאֲךָ מֵאָז, מֵעוֹלָם אָתָּה: נָשְׂאוּ נְהָרוֹת, יהוה, נָשְׂאוּ נְהָרוֹת קוֹלָם, יִשְׂאוּ נְהָרוֹת דָכְיָם: מִקֹּלוֹת מַיִם רַבִּים, אַדִּירִים מִשְׁבְּרֵי יָם, אַדִּיר בַּמָּרוֹם יהוה: עֵדֹתֶיךָ נֶאֶמְנוּ מְאֹד לְבֵיתְךָ נַאֲוָה קֹדֶשׁ, יהוה, לְאֹרֶךְ יָמִים:","cond":["tishaaBeav","fri"]},{"kind":"special","text":"בָּרְכִי נַפְשִׁי אֶת יהוה, יהוה אֱלֹהַי גָּדַלְתָּ מְּאֹד, הוֹד וְהָדָר לָבָשְׁתָּ:\nעֹטֶה אוֹר כַּשַּׂלְמָה נוֹטֶה שָׁמַיִם כַּיְרִיעָה:\nהַמְקָרֶה בַמַּיִם עֲלִיּוֹתָיו, הַשָּׂם עָבִים רְכוּבוֹ, הַמְהַלֵּךְ עַל כַּנְפֵי רוּחַ:\nעֹשֶׂה מַלְאָכָיו רוּחוֹת, מְשָׁרְתָיו אֵשׁ לֹהֵט:\nיָסַד אֶרֶץ עַל מְכוֹנֶיהָ, בַּל תִּמּוֹט עוֹלָם וָעֶד:\nתְּהוֹם כַּלְּבוּשׁ כִּסִּיתוֹ, עַל הָרִים יַעַמְדוּ מָיִם:\nמִן גַּעֲרָתְךָ יְנוּסוּן, מִן קוֹל רַעַמְךָ יֵחָפֵזוּן:\nיַעֲלוּ הָרִים, יֵרְדוּ בְקָעוֹת, אֶל מְקוֹם זֶה יָסַדְתָּ לָהֶם:\nגְּבוּל שַׂמְתָּ בַּל יַעֲבֹרוּן, בַּל יְשׁוּבוּן לְכַסּוֹת הָאָרֶץ:\nהַמְשַׁלֵּחַ מַעְיָנִים בַּנְּחָלִים בֵּין הָרִים יְהַלֵּכוּן:","cond":["tishaaBeav","rh"]},{"kind":"special","text":"יַשְׁקוּ כָּל חַיְתוֹ שָׂדָי, יִשְׁבְּרוּ פְרָאִים צְמָאָם:\nעֲלֵיהֶם עוֹף הַשָּׁמַיִם יִשְׁכּוֹן, מִבֵּין עֳפָאיִם יִתְּנוּ קוֹל:\nמַשְׁקֶה הָרִים מֵעֲלִיּוֹתָיו, מִפְּרִי מַעֲשֶׂיךָ תִּשְׂבַּע הָאָרֶץ:\nמַצְמִיחַ חָצִיר לַבְּהֵמָה וְעֵשֶׂב לַעֲבֹדַת הָאָדָם, לְהוֹצִיא לֶחֶם מִן הָאָרֶץ:\nוְיַיִן יְשַׂמַּח לְבַב אֱנוֹשׁ, לְהַצְהִיל פָּנִים מִשָּׁמֶן, וְלֶחֶם לְבַב אֱנוֹשׁ יִסְעָד:\nיִשְׂבְּעוּ עֲצֵי יהוה, אַרְזֵי לְבָנוֹן אֲשֶׁר נָטָע:\nאֲשֶׁר שָׁם צִפֳּרִים יְקַנֵּנוּ, חֲסִידָה בְּרוֹשִׁים בֵּיתָהּ:\nהָרִים הַגְּבֹהִים לַיְּעֵלִים, סְלָעִים מַחְסֶה לַשְׁפַנִּים:\nעָשָׂה יָרֵחַ לְמוֹעֲדִים, שֶׁמֶשׁ יָדַע מְבוֹאוֹ:\nתָּשֶׁת חֹשֶׁךְ וִיהִי לָיְלָה, בּוֹ תִרְמֹשׂ כָּל חַיְתוֹ יָעַר:\nהַכְּפִירִים שֹׁאֲגִים לַטָּרֶף וּלְבַקֵּשׁ מֵאֵל אָכְלָם:\nתִּזְרַח הַשֶּׁמֶשׁ יֵאָסֵפוּן וְאֶל מְעוֹנֹתָם יִרְבָּצוּן:","cond":["tishaaBeav","rh"]},{"kind":"special","text":"יֵצֵא אָדָם לְפָעֳלוֹ וְלַעֲבֹדָתוֹ עֲדֵי עָרֶב:\nמָה רַבּוּ מַעֲשֶׂיךָ יהוה, כֻּלָּם בְּחָכְמָה עָשִׂיתָ, מָלְאָה הָאָרֶץ קִנְיָנֶךָ:\nזֶה הַיָּם גָּדוֹל וּרְחַב יָדָיִם, שָׁם רֶמֶשׂ וְאֵין מִסְפָּר, חַיּוֹת קְטַנּוֹת עִם גְּדֹלוֹת:\nשָׁם אֳנִיּוֹת יְהַלֵּכוּן, לִוְיָתָן זֶה יָצַרְתָּ לְשַׂחֶק בּוֹ:\nכֻּלָּם אֵלֶיךָ יְשַׂבֵּרוּן לָתֵת אָכְלָם בְּעִתּוֹ:\nתִּתֵּן לָהֶם יִלְקֹטוּן, תִּפְתַּח יָדְךָ יִשְׂבְּעוּן טוֹב:\nתַּסְתִּיר פָּנֶיךָ יִבָּהֵלוּן, תֹּסֵף רוּחָם יִגְוָעוּן וְאֶל עֲפָרָם יְשׁוּבוּן:\nתְּשַׁלַּח רוּחֲךָ יִבָּרֵאוּן וּתְחַדֵּשׁ פְּנֵי אֲדָמָה:\nיְהִי כְבוֹד יהוה לְעוֹלָם, יִשְׂמַח יהוה בְּמַעֲשָׂיו:\nהַמַּבִּיט לָאָרֶץ וַתִּרְעָד, יִגַּע בֶּהָרִים וְיֶעֱשָׁנוּ:\nאָשִׁירָה לַיהוה בְּחַיָּי, אֲזַמְּרָה לֵאלֹהַי בְּעוֹדִי:\nיֶעֱרַב עָלָיו שִׂיחִי, אָנֹכִי אֶשְׂמַח בַּיהוה:\nיִתַּמּוּ חַטָּאִים מִן הָאָרֶץ וּרְשָׁעִים עוֹד אֵינָם, בָּרְכִי נַפְשִׁי אֶת יהוה, הַלְלוּיָהּ:","cond":["tishaaBeav","rh"]},{"kind":"header","text":"הושיענו","cond":["tishaaBeav"]},{"kind":"instruction","text":"בכל יום אחרי שיר של יום אומרים:","cond":["tishaaBeav"]},{"kind":"text","text":"הוֹשִׁיעֵנוּ יהוה אֱלֹהֵינוּ וְקַבְּצֵנוּ מִן הַגּוֹיִם, לְהֹדוֹת לְשֵׁם קָדְשֶׁךָ לְהִשְׁתַּבֵּחַ בִּתְהִלָּתֶךָ: בָּרוּךְ יהוה אֱלֹהֵי יִשְׂרָאֵל מִן הָעוֹלָם וְעַד הָעוֹלָם, וְאָמַר כָּל הָעָם אָמֵן הַלְלוּיָהּ: בָּרוּךְ יהוה מִצִּיּוֹן, שֹׁכֵן יְרוּשָׁלִָם הַלְלוּיָהּ: בָּרוּךְ יהוה אֱלֹהִים אֱלֹהֵי יִשְׂרָאֵל, עֹשֵׂה נִפְלָאוֹת לְבַדּוֹ: וּבָרוּךְ שֵׁם כְּבוֹדוֹ לְעוֹלָם, וְיִמָּלֵא כְבוֹדוֹ אֶת כָּל הָאָרֶץ, אָמֵן וְאָמֵן:","cond":["tishaaBeav"]},{"kind":"instruction","text":"קדיש יתום","cond":["tishaaBeav"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":["tishaaBeav"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":["tishaaBeav"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","ayt"]},{"kind":"header","text":"מזמור לבית האבל","cond":["tishaaBeav"]},{"kind":"instruction","text":"בבית האבל אומרים מזמור זה:","cond":["tishaaBeav","shacharitTachanun"]},{"kind":"text","text":"לַמְנַצֵּחַ לִבְנֵי קֹרַח מִזְמוֹר: שִׁמְעוּ זֹאת כָּל הָעַמִּים, הַאֲזִינוּ כָּל יֹשְׁבֵי חָלֶד: גַּם בְּנֵי אָדָם, גַּם בְּנֵי אִישׁ, יַחַד עָשִׁיר וְאֶבְיוֹן: פִּי יְדַבֵּר חָכְמוֹת, וְהָגוּת לִבִּי תְבוּנוֹת: אַטֶּה לְמָשָׁל אָזְנִי, אֶפְתַּח בְּכִנּוֹר חִידָתִי: לָמָּה אִירָא בִּימֵי רָע, עֲוׂן עֲקֵבַי יְסוּבֵּנִי: הַבֹּטְחִים עַל חֵילָם, וּבְרֹב עָשְׁרָם יִתְהַלָּלוּ: אָח לֹא פָדֹה יִפְדֶּה אִישׁ, לֹא יִתֵּן לֵאלֹהִים כָּפְרוֹ: וְיֵקַר פִּדְיוֹן נַפְשָׁם, וְחָדַל לְעוֹלָם: וִיחִי עוֹד לָנֶצַח, לֹא יִרְאֶה הַשָּׁחַת: כִּי יִרְאֶה חֲכָמִים יָמוּתוּ, יַחַד כְּסִיל וָבַעַר יֹאבֵדוּ, וְעָזְבוּ לַאֲחֵרִים חֵילָם: קִרְבָּם בָּתֵּימוֹ לְעוֹלָם, מִשְׁכְּנֹתָם לְדֹר וָדֹר, קָרְאוּ בִשְׁמוֹתָם עֲלֵי אֲדָמוֹת: וְאָדָם בִּיקָר בַּל יָלִין, נִמְשַׁל כַּבְּהֵמוֹת נִדְמוּ: זֶה דַרְכָּם כֵּסֶל לָמוֹ, וְאַחֲרֵיהֶם בְּפִיהֶם יִרְצוּ סֶלָה: כַּצֹּאן לִשְׁאוֹל שַׁתּוּ מָוֶת יִרְעֵם, וַיִּרְדּוּ בָם יְשָׁרִים לַבֹּקֶר, וְצוּרָם לְבַלּוֹת שְׁאוֹל מִזְּבֻל לוֹ: אַךְ אֱלֹהִים יִפְדֶּה נַפְשִׁי מִיַּד שְׁאוֹל, כִּי יִקָּחֵנִי סֶלָה: אַל תִּירָא כִּי יַעֲשִׁר אִישׁ, כִּי יִרְבֶּה כְּבוֹד בֵּיתוֹ: כִּי לֹא בְמוֹתוֹ יִקַּח הַכֹּל, לֹא יֵרֵד אַחֲרָיו כְּבוֹדוֹ: כִּי נַפְשׁוֹ בְּחַיָּיו יְבָרֵךְ, וְיוֹדֻךָ כִּי תֵיטִיב לָךְ: תָּבוֹא עַד דּוֹר אֲבוֹתָיו, עַד נֵצַח לֹא יִרְאוּ אוֹר: אָדָם בִּיקָר וְלֹא יָבִין נִמְשַׁל כַּבְּהֵמוֹת נִדְמוּ:","cond":["tishaaBeav","shacharitTachanun"]},{"kind":"instruction","text":"בבית האבל אומרים מזמור זה:","cond":["tishaaBeav","noShacharitTachanun"]},{"kind":"text","text":"מִכְתָּם לְדָוִד, שָׁמְרֵנִי אֵל כִּי חָסִיתִי בָךְ: אָמַרְתְּ לַיהוה, אֲדֹנָי אָתָּה, טוֹבָתִי בַּל עָלֶיךָ: לִקְדוֹשִׁים אֲשֶׁר בָּאָרֶץ הֵמָּה, וְאַדִּירֵי כָּל חֶפְצִי בָם: יִרְבּוּ עַצְּבוֹתָם אַחֵר מָהָרוּ, בַּל אַסִּיךְ נִסְכֵּיהֶם מִדָּם, וּבַל אֶשָּׂא אֶת שְׁמוֹתָם עַל שְׂפָתָי: יהוה, מְנָת חֶלְקִי וְכוֹסִי, אַתָּה תּוֹמִיךְ גּוֹרָלִי: חֲבָלִים נָפְלוּ לִי בַּנְּעִמִים, אַף נַחֲלָת שָׁפְרָה עָלָי: אֲבָרֵךְ אֶת יהוה אֲשֶׁר יְעָצָנִי, אַף לֵילוֹת יִסְּרוּנִי כִלְיוֹתָי: שִׁוִּיתִי יהוה לְנֶגְדִּי תָמִיד, כִּי מִימִינִי בַּל אֶמּוֹט: לָכֵן שָׂמַח לִבִּי וַיָּגֶל כְּבוֹדִי, אַף בְּשָׂרִי יִשְׁכֹּן לָבֶטַח: כִּי לֹא תַעֲזֹב נַפְשִׁי לִשְׁאוֹל, לֹא תִתֵּן חֲסִידְךָ לִרְאוֹת שָׁחַת: תּוֹדִיעֵנִי אֹרַח חַיִּים, שֹׂבַע שְׂמָחוֹת אֶת פָּנֶיךָ, נְעִמוֹת בִּימִינְךָ נֶצַח:","cond":["tishaaBeav","noShacharitTachanun"]},{"kind":"instruction","text":"קדיש יתום","cond":["tishaaBeav"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":["tishaaBeav"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":["tishaaBeav"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","ayt"]},{"kind":"header","text":"לדוד","cond":["tishaaBeav","ledavid"]},{"kind":"special","text":"לְדָוִד, יהוה אוֹרִי וְיִשְׁעִי מִמִּי אִירָא, יהוה מָעוֹז חַיַּי מִמִּי אֶפְחָד: בִּקְרֹב עָלַי מְרֵעִים לֶאֱכֹל אֶת בְּשָׂרִי, צָרַי וְאֹיְבַי לִי, הֵמָּה כָשְׁלוּ וְנָפָלוּ: אִם תַּחֲנֶה עָלַי מַחֲנֶה לֹא יִירָא לִבִּי, אִם תָּקוּם עָלַי מִלְחָמָה בְּזֹאת אֲנִי בוֹטֵחַ: אַחַת שָׁאַלְתִּי מֵאֵת יהוה, אוֹתָהּ אֲבַקֵּשׁ, שִׁבְתִּי בְּבֵית יהוה כָּל יְמֵי חַיַּי, לַחֲזוֹת בְּנֹעַם יהוה וּלְבַקֵּר בְּהֵיכָלוֹ: כִּי יִצְפְּנֵנִי בְּסֻכֹּה בְּיוֹם רָעָה יַסְתִּירֵנִי בְּסֵתֶר אָהֳלוֹ, בְּצוּר יְרוֹמְמֵנִי: וְעַתָּה יָרוּם רֹאשִׁי עַל אֹיְבַי סְבִיבוֹתַי, וְאֶזְבְּחָה בְאָהֳלוֹ זִבְחֵי תְרוּעָה, אָשִׁירָה וַאֲזַמְּרָה לַיהוה: שְׁמַע יהוה קוֹלִי אֶקְרָא, וְחָנֵּנִי וַעֲנֵנִי: לְךָ אָמַר לִבִּי בַּקְּשׁוּ פָנַי, אֶת פָּנֶיךָ יהוה אֲבַקֵּשׁ: אַל תַּסְתֵּר פָּנֶיךָ מִמֶּנִּי, אַל תַּט בְּאַף עַבְדֶּךָ, עֶזְרָתִי הָיִיתָ, אַל תִּטְּשֵׁנִי וְאַל תַּעַזְבֵנִי אֱלֹהֵי יִשְׁעִי: כִּי אָבִי וְאִמִּי עֲזָבוּנִי, וַיהוה יַאַסְפֵנִי: הוֹרֵנִי יהוה דַּרְכֶּךָ וּנְחֵנִי בְּאֹרַח מִישׁוֹר לְמַעַן שׁוֹרְרָי: אַל תִּתְּנֵנִי בְּנֶפֶשׁ צָרָי, כִּי קָמוּ בִי עֵדֵי שֶׁקֶר וִיפֵחַ חָמָס: לוּלֵא הֶאֱמַנְתִּי לִרְאוֹת בְּטוּב יהוה בְּאֶרֶץ חַיִּים: קַוֵּה אֶל יהוה, חֲזַק וְיַאֲמֵץ לִבֶּךָ, וְקַוֵּה אֶל יהוה:","cond":["tishaaBeav","ledavid"]},{"kind":"instruction","text":"קדיש יתום","cond":["tishaaBeav","ledavid"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":["tishaaBeav","ledavid"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","ledavid","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","ledavid","ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","ledavid"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","ledavid","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","ledavid","ayt"]},{"kind":"instruction","text":"קדיש יתום","cond":["tishaaBeav"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":["tishaaBeav"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":["tishaaBeav"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","ayt"]},{"kind":"instruction","text":"סיום התפילה","cond":["tishaaBeav"]},{"kind":"text","text":"קַוֵּה אֶל יהוה, חֲזַק וְיַאֲמֵץ לִבֶּךָ, וְקַוֵּה אֶל יהוה:\nאֵין קָדושׁ כַּיהוה, כִּי אֵין בִּלְתֶּךָ, וְאֵין צוּר כֵּאלֹהֵינוּ:\nכִּי מִי אֱלוֹהַּ מִבַּלְעֲדֵי יהוה, וּמִי צוּר זוּלָתִי אֱלֹהֵינוּ:\n\nאֵין כֵּאלֹהֵינוּ, אֵין כַּאדוֹנֵינוּ, אֵין כְּמַלְכֵּנוּ, אֵין כְּמוֹשִׁיעֵנוּ.\nמִי כֵאלֹהֵינוּ, מִי כַאדוֹנֵינוּ, מִי כְמַלְכֵּנוּ, מִי כְמוֹשִׁיעֵנוּ.\nנוֹדֶה לֵאלֹהֵינוּ, נוֹדֶה לַאדוֹנֵינוּ, נוֹדֶה לְמַלְכֵּנוּ, נוֹדֶה לְמוֹשִׁיעֵנוּ.\nבָּרוּךְ אֱלֹהֵינוּ, בָּרוּךְ אֲדוֹנֵינוּ, בָּרוּךְ מַלְכֵּנוּ, בָּרוּךְ מוֹשִׁיעֵנוּ.\nאַתָּה הוּא אֱלֹהֵינוּ, אַתָּה הוּא אֲדוֹנֵינוּ, אַתָּה הוּא מַלְכֵּנוּ, אַתָּה הוּא מוֹשִׁיעֵנוּ. אַתָּה תוֹשִׁיעֵנוּ.\nאַתָּה תָקוּם תְּרַחֵם צִיּון כִּי עֵת לְחֶנְנָהּ כִּי בָא מועֵד:","cond":["tishaaBeav"]},{"kind":"instruction","text":"פיטום הקטורת","cond":["tishaaBeav"]},{"kind":"text","text":"פִּטּוּם הַקְּטֹרֶת: הַצֳּרִי, וְהַצִּפֹּרֶן, הַחֶלְבְּנָה, וְהַלְּבוֹנָה, מִשְׁקַל שִׁבְעִים שִׁבְעִים מָנֶה, מֹר וּקְצִיעָה, שִׁבֹּלֶת נֵרְדְּ, וְכַרְכֹּם מִשְׁקַל שִׁשָּׁה עָשָׂר שִׁשָּׁה עָשָׂר מָנֶה, הַקֹּשְׁטְ שְׁנֵים עָשָׂר, וְקִלּוּפָה שְׁלֹשָׁה, וְקִנָּמוֹן תִּשְׁעָה, בֹּרִית כַּרְשִׁינָה תִּשְׁעָה קַבִּין. יֵין קַפְרִיסִין סְאִין תְּלָתָא וְקַבִּין תְּלָתָא, וְאִם אֵין לוֹ יֵין קַפְרִיסִין מֵבִיא חֲמַר חִוַּרִין עַתִּיק. מֶלַח סְדוֹמִית רֹבַע, מַעֲלֶה עָשָׁן כָּל שֶׁהוּא, רַבִּי נָתָן הַבַּבְלִי אוֹמֵר: אַף כִּפַּת הַיַּרְדֵּן כָּל שֶׁהוּא. וְאִם נָתַן בָּהּ דְּבַשׁ פְּסָלָהּ, וְאִם חִסַּר אַחַת מִכָּל סַמָּנֶיהָ חַיָּב מִיתָה.\n\nרַבָּן שִׁמְעוֹן בֶּן גַּמְלִיאֵל אוֹמֵר: הַצֳּרִי אֵינוֹ אֶלָּא שְׂרָף הַנּוֹטֵף מֵעֲצֵי הַקְּטָף. בֹּרִית כַּרְשִׁינָה שֶׁשָּׁפִין בָּהּ אֶת הַצִּפֹּרֶן כְּדֵי שֶׁתְּהֵא נָאָה, יֵין קַפְרִיסִין שֶׁשּׁוֹרִין בּוֹ אֶת הַצִּפֹּרֶן כְּדֵי שֶׁתְּהֵא עַזָּה. וַהֲלֹא מֵי רַגְלַיִם יָפִין לָהּ, אֶלָּא שֶׁאֵין מַכְנִיסִין מֵי רַגְלַיִם בַּמִקְדָּשׁ מִפְּנֵי הַכָּבוֹד.\n\nתַּנְיָא: רַבִּי נָתָן אוֹמֵר: כְּשֶׁהוּא שׁוֹחֵק אוֹמֵר: \"הָדֵק הֵיטֵב, הֵיטֵב הָדֵק\", מִפְּנֵי שֶׁהַקּול יָפֶה לַבְּשמִים. פִּטְּמָהּ לַחֲצָאִין כְּשֵׁרָה. לִשְׁלִישׁ וְלִרְבִיעַ לֹא שָׁמַעְנוּ. אָמַר רַבִּי יְהוּדָה: זֶה הַכְּלָל: אִם כְּמִדָּתָהּ כְּשֵׁרָה לַחֲצָאִין. וְאִם חִסַּר אַחַת מִכָּל סַמָּנֶיהָ חַיָּב מִיתָה.\n\nתַּנְיָא: בַּר קַפָּרָא אוֹמֵר: אַחַת לְשִׁשִּׁים אוֹ לְשִׁבְעִים שָׁנָה הָיְתָה בָאָה שֶׁל שִׁירַיִם לַחֲצָאִין. וְעוֹד תָּנֵי בַּר קַפָּרָא: אִלּוּ הָיָה נוֹתֵן בָּהּ קוֹרְטוֹב שֶׁל דְּבַשׁ אֵין אָדָם יָכוֹל לַעֲמוֹד מִפְּנֵי רֵיחָהּ, וְלָמָה אֵין מְעָרְבִין בָּהּ דְּבַשׁ? מִפְּנֵי שֶׁהַתּוֹרָה אָמְרָה \"כִּי כָל שְׂאֹר וְכָל דְּבַשׁ לֹא תַקְטִירוּ מִמֶּנּוּ אִשֶּׁה לַיהוה:\"\n\nיהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה:\nיהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה:\nיהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה:\n\nיהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ:\nיהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ:\nיהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ:\n\nיהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:\nיהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:\nיהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:\n\nאַתָּה סֵתֶר לִי מִצַּר תִּצְּרֵנִי רָנֵּי פַלֵּט תְּסוֹבְבֵנִי סֶלָה:\nוְעָרְבָה לַיהוה מִנְחַת יְהוּדָה וִירוּשָׁלָיִם כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמוֹנִיּוֹת:\n\nתָּנָא דְבֵי אֵלִיָּהוּ: כָּל הַשּׁוֹנֶה הֲלָכוֹת בְּכָל יוֹם מֻבְטָח לוֹ שֶׁהוּא בֶּן עוֹלָם הַבָּא, שֶׁנֶּאֱמַר: הֲלִיכוֹת עוֹלָם לוֹ: אַל תִּקְרֵי הֲלִיכות אֶלָּא הֲלָכוֹת. אָמַר רַבִּי אֶלְעָזָר אָמַר רַבִּי חֲנִינָא: תַּלְמִידֵי חֲכָמִים מַרְבִּים שָׁלוֹם בָּעוֹלָם, שֶׁנֶּאֱמַר: וְכָל בָּנַיִךְ לִמּוּדֵי יהוה וְרַב שְׁלוֹם בָּנָיִךְ: אַל תִּקְרֵי בָּנָיִךְ אֶלָּא בּוֹנָיִךְ. שָׁלוֹם רָב לְאֹהֲבֵי תוֹרָתֶךָ, וְאֵין לָמוֹ מִכְשׁוֹל: יְהִי שָׁלוֹם בְּחֵילֵךְ, שַׁלְוָה בְּאַרְמְנוֹתָיִךְ: לְמַעַן אַחַי וְרֵעָי אֲדַבְּרָה נָּא שָׁלוֹם בָּךְ: לְמַעַן בֵּית יהוה אֱלֹהֵינוּ אֲבַקְשָׁה טוֹב לָךְ: יהוה עֹז לְעַמּוֹ יִתֵּן, יהוה יְבָרֵךְ אֶת עַמּוֹ בַשָּׁלוֹם:","cond":["tishaaBeav"]},{"kind":"instruction","text":"קדיש דרבנן","cond":["tishaaBeav"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":["tishaaBeav"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","ayt"]},{"kind":"text","text":"עַל יִשְׂרָאֵל וְעַל רַבָּנָן וְעַל תַּלְמִידֵיהוֹן וְעַל כָּל תַּלְמִידֵי תַלְמִידֵיהוֹן וְעַל כָּל מָאן דְּעָסְקִין בְּאוֹרַיְתָא דִּי בְאַתְרָא (קַדִּישָׁא) הָדֵין וְדִי בְכָל אָתָר וְאָתָר, יְהֵא לְהוֹן וּלְכוֹן שְׁלָמָא רַבָּא חִנָּא וְחִסְדָּא וְרַחֲמֵי וְחַיֵּי אֲרִיכֵי וּמְזוֹנֵי רְוִיחֵי וּפֻרְקָנָא מִן קֳדָם אֲבוּהוֹן דִּי בִשְׁמַיָּא וְאַרְעָא וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":["tishaaBeav"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","ayt"]},{"kind":"header","text":"לדוד","cond":["ledavid"]},{"kind":"special","text":"לְדָוִד, יהוה אוֹרִי וְיִשְׁעִי מִמִּי אִירָא, יהוה מָעוֹז חַיַּי מִמִּי אֶפְחָד: בִּקְרֹב עָלַי מְרֵעִים לֶאֱכֹל אֶת בְּשָׂרִי, צָרַי וְאֹיְבַי לִי, הֵמָּה כָשְׁלוּ וְנָפָלוּ: אִם תַּחֲנֶה עָלַי מַחֲנֶה לֹא יִירָא לִבִּי, אִם תָּקוּם עָלַי מִלְחָמָה בְּזֹאת אֲנִי בוֹטֵחַ: אַחַת שָׁאַלְתִּי מֵאֵת יהוה, אוֹתָהּ אֲבַקֵּשׁ, שִׁבְתִּי בְּבֵית יהוה כָּל יְמֵי חַיַּי, לַחֲזוֹת בְּנֹעַם יהוה וּלְבַקֵּר בְּהֵיכָלוֹ: כִּי יִצְפְּנֵנִי בְּסֻכֹּה בְּיוֹם רָעָה יַסְתִּירֵנִי בְּסֵתֶר אָהֳלוֹ, בְּצוּר יְרוֹמְמֵנִי: וְעַתָּה יָרוּם רֹאשִׁי עַל אֹיְבַי סְבִיבוֹתַי, וְאֶזְבְּחָה בְאָהֳלוֹ זִבְחֵי תְרוּעָה, אָשִׁירָה וַאֲזַמְּרָה לַיהוה: שְׁמַע יהוה קוֹלִי אֶקְרָא, וְחָנֵּנִי וַעֲנֵנִי: לְךָ אָמַר לִבִּי בַּקְּשׁוּ פָנַי, אֶת פָּנֶיךָ יהוה אֲבַקֵּשׁ: אַל תַּסְתֵּר פָּנֶיךָ מִמֶּנִּי, אַל תַּט בְּאַף עַבְדֶּךָ, עֶזְרָתִי הָיִיתָ, אַל תִּטְּשֵׁנִי וְאַל תַּעַזְבֵנִי אֱלֹהֵי יִשְׁעִי: כִּי אָבִי וְאִמִּי עֲזָבוּנִי, וַיהוה יַאַסְפֵנִי: הוֹרֵנִי יהוה דַּרְכֶּךָ וּנְחֵנִי בְּאֹרַח מִישׁוֹר לְמַעַן שׁוֹרְרָי: אַל תִּתְּנֵנִי בְּנֶפֶשׁ צָרָי, כִּי קָמוּ בִי עֵדֵי שֶׁקֶר וִיפֵחַ חָמָס: לוּלֵא הֶאֱמַנְתִּי לִרְאוֹת בְּטוּב יהוה בְּאֶרֶץ חַיִּים: קַוֵּה אֶל יהוה, חֲזַק וְיַאֲמֵץ לִבֶּךָ, וְקַוֵּה אֶל יהוה:","cond":["ledavid"]},{"kind":"instruction","text":"קדיש יתום","cond":["ledavid"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":["ledavid"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ledavid","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ledavid","ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":["ledavid"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ledavid","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ledavid","ayt"]}],"arvit":[{"kind":"special","text":"תפילת יום העצמאות ויום שחרור ירושלים","cond":["yerushalayim"]},{"kind":"instruction","text":"לפני התפילה אומרים:","cond":["yerushalayim"]},{"kind":"instruction","text":"תהלים פרק ק\"ז","cond":["yerushalayim"]},{"kind":"text","text":"הֹדוּ לַיהוה כִּי-טוֹב, כִּי לְעוֹלָם חַסְדּוֹ: יֹאמְרוּ גְּאוּלֵי יהוה אֲשֶׁר גְּאָלָם מִיַּד-צָר: וּמֵאֲרָצוֹת קִבְּצָם, מִמִּזְרָח וּמִמַּעֲרָב מִצָּפוֹן וּמִיָּם: תָּעוּ בַמִּדְבָּר בִּישִׁימוֹן דָּרֶךְ, עִיר מוֹשָׁב לֹא מָצָאוּ: רְעֵבִים גַּם-צְמֵאִים, נַפְשָׁם בָּהֶם תִּתְעַטָּף: וַיִּצְעֲקוּ אֶל-יהוה בַּצַּר לָהֶם, מִמְּצוּקוֹתֵיהֶם יַצִּילֵם: וַיַּדְרִיכֵם בְּדֶרֶךְ יְשָׁרָה, לָלֶכֶת אֶל-עִיר מוֹשָׁב: יוֹדוּ לַיהוה חַסְדּוֹ, וְנִפְלְאוֹתָיו לִבְנֵי אָדָם: כִּי-הִשְׂבִּיעַ נֶפֶשׁ שׁוֹקֵקָה, וְנֶפֶשׁ רְעֵבָה מִלֵּא-טוֹב: יֹשְׁבֵי חֹשֶׁךְ וְצַלְמָוֶת, אֲסִירֵי עֳנִי וּבַרְזֶל: כִּי-הִמְרוּ אִמְרֵי-אֵל, וַעֲצַת עֶלְיוֹן נָאָצוּ: וַיַּכְנַע בֶּעָמָל לִבָּם, כָּשְׁלוּ וְאֵין עֹזֵר: וַיִּזְעֲקוּ אֶל-יהוה בַּצַּר לָהֶם, מִמְּצֻקוֹתֵיהֶם יוֹשִׁיעֵם: יוֹצִיאֵם מֵחֹשֶׁךְ וְצַלְמָוֶת, וּמוֹסְרוֹתֵיהֶם יְנַתֵּק: יוֹדוּ לַיהוה חַסְדּוֹ, וְנִפְלְאוֹתָיו לִבְנֵי אָדָם: כִּי-שִׁבַּר דַּלְתוֹת נְחֹשֶׁת, וּבְרִיחֵי בַרְזֶל גִּדֵּעַ: אֱוִלִים מִדֶּרֶךְ פִּשְׁעָם, וּמֵעֲוׂנֹתֵיהֶם יִתְעַנּוּ: כָּל-אֹכֶל תְּתַעֵב נַפְשָׁם, וַיַּגִּיעוּ עַד-שַׁעֲרֵי מָוֶת: וַיִּזְעֲקוּ אֶל-יהוה בַּצַּר לָהֶם, מִמְּצֻקוֹתֵיהֶם יוֹשִׁיעֵם: יִשְׁלַח דְּבָרוֹ וְיִרְפָּאֵם, וִימַלֵּט מִשְּׁחִיתוֹתָם: יוֹדוּ לַיהוה חַסְדּוֹ, וְנִפְלְאוֹתָיו לִבְנֵי אָדָם: וְיִזְבְּחוּ זִבְחֵי תוֹדָה, וִיסַפְּרוּ מַעֲשָׂיו בְּרִנָּה: יוֹרְדֵי הַיָּם בָּאֳנִיּוֹת, עֹשֵׂי מְלָאכָה בְּמַיִם רַבִּים: הֵמָּה רָאוּ מַעֲשֵׂי יהוה וְנִפְלְאוֹתָיו בִּמְצוּלָה: וַיּאמֶר, וַיַּעֲמֵד רוּחַ סְעָרָה, וַתְּרוֹמֵם גַּלָּיו: יַעֲלוּ שָׁמַיִם יֵרְדוּ תְהוֹמוֹת, נַפְשָׁם בְּרָעָה תִתְמוֹגָג: יָחוֹגּוּ וְיָנוּעוּ כַּשִּׁכּוֹר, וְכָל-חָכְמָתָם תִּתְבַּלָּע: וַיִּצְעֲקוּ אֶל-יהוה בַּצַּר לָהֶם, וּמִמְּצוּקתֵיהֶם יוֹצִיאֵם: יָקֵם סְעָרָה לִדְמָמָה, וַיֶּחֱשׁוּ גַּלֵּיהֶם: וַיִּשְׂמְחוּ כִי-יִשְׁתֹּקוּ, וַיַּנְחֵם אֶל-מְחוֹז חֶפְצָם: יוֹדוּ לַיהוה חַסְדּוֹ, וְנִפְלְאוֹתָיו לִבְנֵי אָדָם: וִירוֹמְמוּהוּ בִּקְהַל-עָם, וּבְמוֹשַׁב זְקֵנִים יְהַלְלוּהוּ: יָשֵׂם נְהָרוֹת לְמִדְבָּר, וּמֹצָאֵי מַיִם לְצִמָּאוֹן: אֶרֶץ פְּרִי לִמְלֵחָה מֵרָעַת יוֹשְׁבֵי בָהּ: יָשֵׂם מִדְבָּר לַאֲגַם-מַיִם, וְאֶרֶץ צִיָּה לְמֹצָאֵי מָיִם: וַיּוֹשֶׁב שָׁם רְעֵבִים, וַיְכוֹנְנוּ עִיר מוֹשָׁב: וַיִּזְרְעוּ שָׂדוֹת וַיִּטְּעוּ כְרָמִים, וַיַּעֲשׂוּ פְּרִי תְבוּאָה: וַיְבָרְכֵם וַיִּרְבּוּ מְאֹד, וּבְהֶמְתָּם לֹא יַמְעִיט: וַיִּמְעֲטוּ וַיָּשֹׁחוּ מֵעֹצֶר רָעָה וְיָגוֹן: שֹׁפֵךְ בּוּז עַל-נְדִיבִים, וַיַּתְעֵם בְּתֹהוּ לֹא-דָרֶךְ: וַיְשַׂגֵּב אֶבְיוֹן מֵעוֹנִי, וַיָּשֶׂם כַּצֹּאן מִשְׁפָּחוֹת: יִרְאוּ יְשָׁרִים וְיִשְׂמָחוּ, וְכָל-עַוְלָה קָפְצָה פִּיהָ: מִי-חָכָם וְיִשְׁמָר-אֵלֶּה, וְיִתְבּוֹנְנוּ חַסְדֵּי יהוה:","cond":["yerushalayim"]},{"kind":"instruction","text":"תהלים פרק צ\"ז","cond":["yerushalayim"]},{"kind":"text","text":"יהוה מָלָךְ תָּגֵל הָאָרֶץ, יִשְׂמְחוּ אִיִּים רַבִּים: עָנָן וַעֲרָפֶל סְבִיבָיו, צֶדֶק וּמִשְׁפָּט מְכוֹן כִּסְאוֹ: אֵשׁ לְפָנָיו תֵּלֵךְ וּתְלַהֵט סָבִיב צָרָיו: הֵאִירוּ בְרָקָיו תֵּבֵל, רָאֲתָה וַתָּחֵל הָאָרֶץ: הָרִים כַּדּוֹנַג נָמַסּוּ, מִלִּפְנֵי יהוה, מִלִּפְנֵי אֲדוֹן כָּל-הָאָרֶץ: הִגִּידוּ הַשָּׁמַיִם צִדְקוֹ וְרָאוּ כָל-הָעַמִּים כְּבוֹדוֹ: יֵבשׁוּ כָּל-עֹבְדֵי פֶסֶל הַמִּתְהַלְלִים בָּאֱלִילִים, הִשְׁתַּחֲווּ-לוֹ כָּל-אֱלֹהִים: שָׁמְעָה וַתִּשְׂמַח צִיּוֹן וַתָּגֵלְנָה בְּנוֹת יְהוּדָה, לְמַעַן מִשְׁפָּטֶיךָ, יהוה: כִּי-אַתָּה יהוה עֶלְיוֹן עַל-כָּל-הָאָרֶץ, מְאֹד נַעֲלֵיתָ עַל-כָּל-אֱלֹהִים: אֹהֲבֵי יהוה שִׂנְאוּ רָע, שֹׁמֵר נַפְשׁוֹת חֲסִידָיו, מִיַּד רְשָׁעִים יַצִּילֵם: אוֹר זָרֻעַ לַצַּדִּיק וּלְיִשְׁרֵי-לֵב שִׂמְחָה: שִׂמְחוּ צַדִּיקִים בַּיהוה, וְהוֹדוּ לְזֵכֶר קָדְשׁוֹ:","cond":["yerushalayim"]},{"kind":"instruction","text":"תהלים פרק צ\"ח","cond":["yerushalayim"]},{"kind":"text","text":"מִזְמוֹר, שִׁירוּ לַיהוה שִׁיר חָדָשׁ כִּי-נִפְלָאוֹת עָשָׂה, הוֹשִׁיעָה-לּוֹ יְמִינוֹ וּזְרוֹעַ קָדְשׁוֹ: הוֹדִיעַ יהוה יְשׁוּעָתוֹ, לְעֵינֵי הַגּוֹיִם גִּלָּה צִדְקָתוֹ: זָכַר חַסְדּוֹ וֶאֱמוּנָתוֹ לְבֵית יִשְׂרָאֵל, רָאוּ כָל-אַפְסֵי-אָרֶץ אֵת יְשׁוּעַת אֱלֹהֵינוּ: הָרִיעוּ לַיהוה כָּל-הָאָרֶץ, פִּצְחוּ וְרַנְּנוּ וְזַמֵּרוּ: זַמְּרוּ לַיהוה בְּכִנּוֹר, בְּכִנּוֹר וְקוֹל זִמְרָה: בַּחֲצֹצְרוֹת וְקוֹל שׁוֹפָר, הָרִיעוּ לִפְנֵי הַמֶּלֶךְ יהוה: יִרְעַם הַיָּם וּמְלֹאוֹ, תֵּבֵל וְישְׁבֵי בָהּ: נְהָרוֹת יִמְחֲאוּ-כָף, יַחַד הָרִים יְרַנֵּנוּ: לִפְנֵי-יהוה כִּי בָא לִשְׁפֹּט הָאָרֶץ, יִשְׁפֹּט-תֵּבֵל בְּצֶדֶק וְעַמִּים בְּמֵישָׁרִים:","cond":["yerushalayim"]},{"kind":"instruction","text":"ואומרים בית בית:","cond":["yerushalayim"]},{"kind":"text","text":"הִתְעוֹרְרִי הִתְעוֹרְרִי,\nכִּי בָא אוֹרֵךְ קוּמִי אוֹרִי.\nעוּרִי עוּרִי שִׁיר דַּבֵּרִי,\nכְּבוֹד יהוה עָלַיִךְ נִגְלָה.\nזֶה הַיּוֹם עָשָׂה יהוה, נָגִילָה וְנִשְׂמְחָה בוֹ:\n\nלֹא תֵּבֹשִׁי וְלֹא תִּכָּלְמִי\nמַה תִּשְׁתּוֹחֲחִי וּמַה תֶּהֱמִי\nבָּךְ יֶחֱסוּ עֲנִיֵּי עַמִּי\nוְנִבְנְתָה עִיר עַל תִּלָּהּ\nזֶה הַיּוֹם עָשָׂה יהוה, נָגִילָה וְנִשְׂמְחָה בוֹ:\n\nיָמִין וּשְׂמֹאל תִּפְרֹצִי\nוְאֶת יהוה תַּעֲרִיצִי\nעַל יַד אִישׁ בֶּן פַּרְצִי\nוְנִשְׂמְחָה וְנָגִילָה\nזֶה הַיּוֹם עָשָׂה יהוה, נָגִילָה וְנִשְׂמְחָה בוֹ:","cond":["yerushalayim"]},{"kind":"header","text":"תפילת ערבית","cond":["yerushalayim"]},{"kind":"instruction","text":"יש אומרים פסוקים אלה וחצי קדיש לפני התפילה:","cond":[]},{"kind":"text","text":"שִׁיר הַמַּעֲלוֹת, הִנֵּה בָּרְכוּ אֶת יהוה כָּל עַבְדֵי יהוה, הָעֹמְדִים בְּבֵית יהוה בַּלֵּילוֹת: שְׂאוּ יְדֵיכֶם קֹדֶשׁ וּבָרְכוּ אֶת יהוה: יְבָרֶכְךָ יהוה מִצִּיּוֹן, עֹשֵׂה שָׁמַיִם וָאָרֶץ:","cond":[]},{"kind":"text","text":"יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה:\nיהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה:\nיהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה:\n\nיהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ:\nיהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ:\nיהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ:\n\nיהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:\nיהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:\nיהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:\n\nהושִׁיעָה אֶת עַמֶּךָ וּבָרֵךְ אֶת נַחֲלָתֶךָ וּרְעֵם וְנַשְּׂאֵם עַד הָעוֹלָם: מִי יִתֵּן מִצִּיּוֹן יְשׁוּעַת יִשְׂרָאֵל בְּשׁוּב יהוה שְׁבוּת עַמּוֹ, יָגֵל יַעֲקֹב, יִשְׂמַח יִשְׂרָאֵל: בְּשָׁלוֹם יַחְדָּו אֶשְׁכְּבָה וְאִישָׁן, כִּי אַתָּה יהוה לְבָדָד לָבֶטַח תּוֹשִׁיבֵנִי: יוֹמָם יְצַוֶּה יהוה חַסְדּוֹ, וּבַלַּיְלָה שִׁירֹה עִמִּי, תְּפִלָּה לְאֵל חַיָּי: וּתְשׁוּעַת צַדִּיקִים מֵיהוה, מָעוּזָּם בְּעֵת צָרָה: וַיַּעְזְרֵם יהוה וַיְפַלְּטֵם, יְפַלְּטֵם מֵרְשָׁעִים וְיוֹשִׁיעֵם כִּי חָסוּ בוֹ:","cond":[]},{"kind":"instruction","text":"חצי קדיש","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":[]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית, וְהִרְבָּה לְהָשִׁיב אַפּוֹ וְלֹא יָעִיר כָּל חֲמָתוֹ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":[]},{"kind":"instruction","text":"חזן:","cond":[]},{"kind":"text","text":"בָּרְכוּ אֶת יהוה הַמְבֹרָךְ.","cond":[]},{"kind":"instruction","text":"קהל וחזן:","cond":[]},{"kind":"text","text":"בָּרוּךְ יהוה הַמְבֹרָךְ לְעוֹלָם וָעֶד.","cond":[]},{"kind":"instruction","text":"ברכות קריאת שמע","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר בִּדְבָרוֹ מַעֲרִיב עֲרָבִים, בְּחָכְמָה פּוֹתֵחַ שְׁעָרִים, וּבִתְבוּנָה מְשַׁנֶּה עִתִּים וּמַחֲלִיף אֶת הַזְּמַנִּים, וּמְסַדֵּר אֶת הַכּוֹכָבִים בְּמִשְׁמְרוֹתֵיהֶם בָּרָקִיעַ כִּרְצוֹנוֹ, בּוֹרֵא יוֹם וָלָיְלָה, גּוֹלֵל אוֹר מִפְּנֵי חֹשֶׁךְ וְחֹשֶׁךְ מִפְּנֵי אוֹר, וּמַעֲבִיר יוֹם וּמֵבִיא לָיְלָה, וּמַבְדִּיל בֵּין יוֹם וּבֵין לָיְלָה, יהוה צְבָאוֹת שְׁמוֹ. אֵל חַי וְקַיָּם תָּמִיד, יִמְלֹךְ עָלֵינוּ לְעוֹלָם וָעֶד. בָּרוּךְ אַתָּה יהוה, הַמַּעֲרִיב עֲרָבִים.\n\nאַהֲבַת עוֹלָם בֵּית יִשְׂרָאֵל עַמְּךָ אָהַבְתָּ, תּוֹרָה וּמִצְוׂת חֻקִּים וּמִשְׁפָּטִים אוֹתָנוּ לִמַּדְתָּ, עַל כֵּן יהוה אֱלֹהֵינוּ, בְּשָׁכְבֵנוּ וּבְקוּמֵנוּ נָשִׂיחַ בְּחֻקֶּיךָ, וְנִשְׂמַח בְּדִבְרֵי תַלְמוּד תּוֹרָתֶךָ וּבְמִצְוׂתֶיךָ לְעוֹלָם וָעֶד, כִּי הֵם חַיֵּינוּ וְאֹרֶךְ יָמֵינוּ, וּבָהֶם נֶהְגֶּה יוֹמָם וָלָיְלָה. וְאַהֲבָתְךָ אַל תָּסִיר מִמֶּנּוּ לְעוֹלָמִים. בָּרוּךְ אַתָּה יהוה, אוֹהֵב עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"header","text":"קריאת שמע","cond":[]},{"kind":"instruction","text":"יחיד אומר:","cond":[]},{"kind":"text","text":"אֵל מֶלֶךְ נֶאֱמָן.","cond":[]},{"kind":"text","text":"שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:","cond":[]},{"kind":"instruction","text":"בלחש:","cond":[]},{"kind":"text","text":"בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד.\n\nוְאָהַבְתָּ אֵת יהוה אֱלֹהֶיךָ, בְּכָל לְבָבְךָ וּבְכָל נַפְשְׁךָ וּבְכָל מְאֹדֶךָ: וְהָיוּ הַדְּבָרִים הָאֵלֶּה אֲשֶׁר אָנֹכִי מְצַוְּךָ הַיּוֹם, עַל לְבָבֶךָ: וְשִׁנַּנְתָּם לְבָנֶיךָ וְדִבַּרְתָּ בָּם, בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ: וּקְשַׁרְתָּם לְאוֹת עַל יָדֶךָ, וְהָיוּ לְטֹטָפֹת בֵּין עֵינֶיךָ: וּכְתַבְתָּם עַל מְזֻזוֹת בֵּיתֶךָ וּבִשְׁעָרֶיךָ:","cond":[]},{"kind":"text","text":"וְהָיָה אִם שָׁמֹעַ תִּשְׁמְעוּ אֶל מִצְוׂתַי, אֲשֶׁר אָנֹכִי מְצַוֶּה אֶתְכֶם הַיּוֹם, לְאַהֲבָה אֶת יהוה אֱלֹהֵיכֶם וּלְעָבְדוֹ, בְּכָל לְבַבְכֶם וּבְכָל נַפְשְׁכֶם: וְנָתַתִּי מְטַר אַרְצְכֶם בְּעִתּוֹ, יוֹרֶה וּמַלְקוֹשׁ, וְאָסַפְתָּ דְגָנֶךָ וְתִירֹשְׁךָ וְיִצְהָרֶךָ: וְנָתַתִּי עֵשֶׂב בְּשָׂדְךָ לִבְהֶמְתֶּךָ, וְאָכַלְתָּ וְשָׂבָעְתָּ: הִשָּׁמְרוּ לָכֶם פֶּן יִפְתֶּה לְבַבְכֶם, וְסַרְתֶּם וַעֲבַדְתֶּם אֱלֹהִים אֲחֵרִים וְהִשְׁתַּחֲוִיתֶם לָהֶם: וְחָרָה אַף יהוה בָּכֶם, וְעָצַר אֶת הַשָּׁמַיִם וְלֹא יִהְיֶה מָטָר, וְהָאֲדָמָה לֹא תִתֵּן אֶת יְבוּלָהּ, וַאֲבַדְתֶּם מְהֵרָה מֵעַל הָאָרֶץ הַטֹּבָה אֲשֶׁר יהוה נֹתֵן לָכֶם: וְשַׂמְתֶּם אֶת דְּבָרַי אֵלֶּה עַל לְבַבְכֶם וְעַל נַפְשְׁכֶם, וּקְשַׁרְתֶּם אֹתָם לְאוֹת עַל יֶדְכֶם וְהָיוּ לְטוֹטָפֹת בֵּין עֵינֵיכֶם: וְלִמַּדְתֶּם אֹתָם אֶת בְּנֵיכֶם לְדַבֵּר בָּם, בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ: וּכְתַבְתָּם עַל מְזוּזוֹת בֵּיתֶךָ וּבִשְׁעָרֶיךָ: לְמַעַן יִרְבּוּ יְמֵיכֶם וִימֵי בְנֵיכֶם עַל הָאֲדָמָה אֲשֶׁר נִשְׁבַּע יהוה לַאֲבֹתֵיכֶם לָתֵת לָהֶם, כִּימֵי הַשָּׁמַיִם עַל הָאָרֶץ:","cond":[]},{"kind":"text","text":"וַיֹּאמֶר יהוה אֶל מֹשֶׁה לֵּאמֹר: דַּבֵּר אֶל בְּנֵי יִשְׂרָאֵל וְאָמַרְתָּ אֲלֵהֶם, וְעָשׂוּ לָהֶם צִיצִת עַל כַּנְפֵי בִגְדֵיהֶם לְדֹרֹתָם, וְנָתְנוּ עַל צִיצִת הַכָּנָף פְּתִיל תְּכֵלֶת: וְהָיָה לָכֶם לְצִיצִת, וּרְאִיתֶם אֹתוֹ, וּזְכַרְתֶּם אֶת כָּל מִצְוׂת יהוה וַעֲשִׂיתֶם אֹתָם, וְלֹא תָתֻרוּ אַחֲרֵי לְבַבְכֶם וְאַחֲרֵי עֵינֵיכֶם אֲשֶׁר אַתֶּם זֹנִים אַחֲרֵיהֶם: לְמַעַן תִּזְכְּרוּ וַעֲשִׂיתֶם אֶת כָּל מִצְוׂתָי, וִהְיִיתֶם קְדֹשִׁים לֵאלֹהֵיכֶם: אֲנִי יהוה אֱלֹהֵיכֶם אֲשֶׁר הוֹצֵאתִי אֶתְכֶם מֵאֶרֶץ מִצְרַיִם, לִהְיוֹת לָכֶם לֵאלֹהִים, אֲנִי יהוה אֱלֹהֵיכֶם:","cond":[]},{"kind":"text","text":"אֱמֶת","cond":[]},{"kind":"instruction","text":"הש\"ץ חוזר ואומר:","cond":[]},{"kind":"text","text":"יהוה אֱלֹהֵיכֶם: אֱמֶת\n\nוֶאֱמוּנָה כָּל זֹאת וְקַיָּם עָלֵינוּ, כִּי הוּא יהוה אֱלֹהֵינוּ וְאֵין זוּלָתוֹ, וַאֲנַחְנוּ יִשׂרָאֵל עַמּוֹ. הַפּוֹדֵנוּ מִיַּד מְלָכִים, מַלְכֵּנוּ הַגּוֹאֲלֵנוּ מִכַּף כָּל הֶעָרִיצִים, הָאֵל הַנִּפְרָע לָנוּ מִצָּרֵינוּ, וְהַמְשַׁלֵּם גְּמוּל לְכָל אוֹיְבֵי נַפְשֵׁנוּ. הָעוֹשֶׂה גְדוֹלוֹת עַד אֵין חֵקֶר, נִסִּים וְנִפְלָאוֹת עַד אֵין מִסְפָּר, הַשָּׂם נַפְשֵׁנוּ בַּחַיִּים, וְלֹא נָתַן לַמּוֹט רַגְלֵנוּ. הַמַּדְרִיכֵנוּ עַל בָּמוֹת אוֹיְבֵינוּ, וַיָּרֶם קַרְנֵנוּ עַל כָּל שׂוֹנְאֵינוּ. הָעוֹשֶׂה לָּנוּ נִסִּים וּנְקָמָה בְּפַרְעה, אוֹתוֹת וּמוֹפְתִים בְּאַדְמַת בְּנֵי חָם, הַמַּכֶּה בְעֶבְרָתוֹ כָּל בְּכוֹרֵי מִצְרָיִם, וַיּוֹצֵא אֶת עַמּוֹ יִשְׂרָאֵל מִתּוֹכָם לְחֵרוּת עוֹלָם. הַמַּעֲבִיר בָּנָיו בֵּין גִּזְרֵי יַם סוּף, אֶת רוֹדְפֵיהֶם וְאֶת שׂוֹנְאֵיהֶם בִּתְהוֹמוֹת טִבַּע. וְרָאוּ בָנָיו גְּבוּרָתוֹ, שִׁבְּחוּ וְהוֹדוּ לִשְׁמוֹ. וּמַלְכוּתוֹ, בְּרָצון קִבְּלוּ עֲלֵיהֶם, משֶׁה וּבְנֵי יִשְׂרָאֵל לְךָ עָנוּ שִׁירָה בְּשִׂמְחָה רַבָּה, וְאָמְרוּ כֻלָּם:\n\nמִי כָמֹכָה בָּאֵלִם יהוה, מִי כָּמֹכָה נֶאְדָּר בַּקֹּדֶשׁ, נוֹרָא תְהִלֹּת עֹשֵׂה פֶלֶא:\n\nמַלְכוּתְךָ רָאוּ בָנֶיךָ, בּוֹקֵעַ יָם לִפְנֵי משֶׁה, \"זֶה אֵלִי\" עָנוּ, וְאָמְרוּ:\n\nיהוה יִמְלֹךְ לְעֹלָם וָעֶד:\n\nוְנֶאֱמַר: כִּי פָדָה יהוה אֶת יַעֲקֹב וּגְאָלוֹ מִיַּד חָזָק מִמֶּנּוּ: בָּרוּךְ אַתָּה יהוה, גָּאַל יִשְׂרָאֵל.\n\n\nהַשְׁכִּיבֵנוּ יהוה אֱלֹהֵינוּ לְשָׁלוֹם, וְהַעֲמִידֵנוּ מַלְכֵּנוּ לְחַיִּים טוֹבִים וּלְשָׁלוֹם, וּפְרוֹשׂ עָלֵינוּ סֻכַּת שְׁלוֹמֶךָ, וְתַקְּנֵנוּ בְּעֵצָה טוֹבָה מִלְּפָנֶיךָ, וְהוֹשִׁיעֵנוּ מְהֵרַה לְמַעַן שְׁמֶךָ. וְהָגֵן בַּעֲדֵנוּ, וְהָסֵר מֵעָלֵינוּ אוֹיֵב, דֶּבֶר וְחֶרֶב וְרָעָב וְיָגוֹן. וְהָסֵר שָׂטָן מִלְּפָנֵינוּ וּמֵאַחֲרֵינוּ, וּבְצֵל כְּנָפֶיךָ תַּסְתִּירֵנוּ, כִּי אֵל שׁוֹמְרֵנוּ וּמַצִּילֵנוּ אָתָּה, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה. וּשְׁמוֹר צֵאתֵנוּ וּבוֹאֵנוּ לְחַיִּים וּלְשָׁלוֹם מֵעַתָּה וְעַד עוֹלָם. בָּרוּךְ אַתָּה יהוה, שׁוֹמֵר עַמּוֹ יִשְׂרָאֵל לָעַד.","cond":[]},{"kind":"text","text":"בָּרוּךְ יהוה לְעוֹלָם אָמֵן וְאָמֵן: בָּרוּךְ יהוה מִצִּיּוֹן, שֹׁכֵן יְרוּשָׁלָיִם הַלְלוּיָהּ: בָּרוּךְ יהוה אֱלֹהִים אֱלֹהֵי יִשְׂרָאֵל, עֹשֵׂה נִפְלָאוֹת לְבַדּוֹ: וּבָרוּךְ שֵׁם כְּבוֹדוֹ לְעוֹלָם, וְיִמָּלֵא כְבוֹדוֹ אֶת כָּל הָאָרֶץ אָמֵן וְאָמֵן: יְהִי כְבוֹד יהוה לְעוֹלָם, יִשְׂמַח יהוה בְּמַעֲשָׂיו: יְהִי שֵׁם יהוה מְבֹרָךְ מֵעַתָּה וְעַד עוֹלָם: כִּי לֹא יִטֹּשׁ יהוה אֶת עַמּו בַּעֲבוּר שְׁמוֹ הַגָּדוֹל, כִּי הוֹאִיל יהוה לַעֲשׂוֹת אֶתְכֶם לוֹ לְעָם: וַיַּרְא כָּל הָעָם וַיִּפְּלוּ עַל פְּנֵיהֶם וַיֹּאמְרוּ, יהוה הוּא הָאֱלֹהִים, יהוה הוּא הָאֱלֹהִים: וְהָיָה יהוה לְמֶלֶךְ עַל כָּל הָאָרֶץ, בַּיּוֹם הַהוּא יִהְיֶה יהוה אֶחָד וּשְׁמוֹ אֶחָד: יְהִי חַסְדְּךָ יהוה עָלֵינוּ כַּאֲשֶׁר יִחַלְנוּ לָךְ: הוֹשִׁיעֵנוּ יהוה אֱלֹהֵינוּ וְקַבְּצֵנוּ מִן הַגּוֹיִם, לְהוֹדוֹת לְשֵׁם קָדְשֶׁךָ לְהִשְׁתַּבֵּחַ בִּתְהִלָּתֶךָ: כָּל גּוֹיִם אֲשֶׁר עָשִׂיתָ יָבֹאוּ וְיִשְׁתַּחֲווּ לְפָנֶיךָ אֲדֹנָי וִיכַבְּדוּ לִשְׁמֶךָ: כִּי גָדוֹל אַתָּה וְעֹשֵׂה נִפְלָאוֹת, אַתָּה אֱלֹהִים לְבַדֶּךָ: וַאֲנַחְנוּ עַמְּךָ וְצֹאן מַרְעִיתֶךָ נוֹדֶה לְךָ לְעוֹלָם, לְדוֹר וָדוֹר נְסַפֵּר תְּהִלָּתֶךָ: בָּרוּךְ יהוה בַּיּוֹם, בָּרוּךְ יהוה בַּלָּיְלָה, בָּרוּךְ יהוה בְּשָׁכְבֵנוּ, בָּרוּךְ יהוה בְּקוּמֵנוּ. כִּי בְיָדְךָ נַפְשׁוֹת הַחַיִּים וְהַמֵּתִים. אֲשֶׁר בְּיָדוֹ נֶפֶשׁ כָּל חָי וְרוּחַ כָּל בְּשָׂר אִישׁ: בְּיָדְךָ אַפְקִיד רוּחִי, פָּדִיתָה אוֹתִי יהוה אֵל אֱמֶת: אֱלֹהֵינוּ שֶׁבַּשָּׁמַיִם, יַחֵד שִׁמְךָ וְקַיֵּם מַלְכוּתְךָ תָּמִיד, וּמְלֹךְ עָלֵינוּ לְעוֹלָם וָעֶד. יִרְאוּ עֵינֵינוּ וְיִשְׂמַח לִבֵּנוּ וְתָגֵל נַפְשֵׁנוּ בִּישׁוּעָתְךָ בֶּאֱמֶת בֶּאֱמֹר לְצִיּוֹן מָלַךְ אֱלֹהָיִךְ. יהוה מֶלֶךְ, יהוה מָלָךְ, יהוה יִמְלֹךְ לְעוֹלָם וָעֶד. כִּי הַמַּלְכוּת שֶׁלְּךָ הִיא, וּלְעוֹלְמֵי עַד תִּמְלֹךְ בְּכָבוֹד, כִּי אֵין לָנוּ מֶלֶךְ אֶלָּא אָתָּה. בָּרוּךְ אַתָּה יהוה, הַמֶּלֶךְ בִּכְבוֹדוֹ תָּמִיד יִמְלֹךְ עָלֵינוּ לְעוֹלָם וָעֶד וְעַל כָּל מַעֲשָׂיו.","cond":["chul"]},{"kind":"instruction","text":"חצי קדיש","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":[]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"header","text":"עמידה","cond":[]},{"kind":"instruction","text":"תפילת העמידה","cond":[]},{"kind":"text","text":"אֲדֹנָי, שְׂפָתַי תִּפְתָּח, וּפִי יַגִּיד תְּהִלָּתֶךָ:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק, וֵאלֹהֵי יַעֲקֹב, הָאֵל הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, וְקוֹנֵה הַכֹּל, וְזוֹכֵר חַסְדֵי אָבוֹת, וּמֵבִיא גוֹאֵל לִבְנֵי בְנֵיהֶם לְמַעַן שְׁמוֹ בְּאַהֲבָה.","cond":[]},{"kind":"special","text":"זָכְרֵנוּ לְחַיִּים, מֶלֶךְ חָפֵץ בַּחַיִּים, וְכָתְבֵנוּ בְּסֵפֶר הַחַיִּים, לְמַעַנְךָ אֱלֹהִים חַיִּים.","cond":["ayt"]},{"kind":"text","text":"מֶלֶךְ עוֹזֵר וּמוֹשִׁיעַ וּמָגֵן. בָּרוּךְ אַתָּה יהוה, מָגֵן אַבְרָהָם.","cond":[]},{"kind":"text","text":"אַתָּה גִּבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֵּה מֵתִים אַתָּה רַב לְהוֹשִׁיעַ,","cond":[]},{"kind":"summer","text":"מוֹרִיד הַטָּל,","cond":["summerTal"]},{"kind":"winter","text":"מַשִּׁיב הָרוּחַ וּמוֹרִיד הַגֶּשֶׁם,","cond":["winterTal"]},{"kind":"text","text":"מְכַלְכֵּל חַיִּים בְּחֶסֶד, מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים, סוֹמֵךְ נוֹפְלִים, וְרוֹפֵא חוֹלִים וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמוּנָתוֹ לִישֵׁנֵי עָפָר. מִי כָמוֹךָ בַּעַל גְּבוּרוֹת וּמִי דּוֹמֶה לָךְ, מֶלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִיחַ יְשׁוּעָה.","cond":[]},{"kind":"special","text":"מִי כָמוֹךָ אַב הָרַחֲמָן, זוֹכֵר יְצוּרָיו לְחַיִּים בְּרַחֲמִים.","cond":["ayt"]},{"kind":"text","text":"וְנֶאֱמָן אַתָּה לְהַחֲיוֹת מֵתִים. בָּרוּךְ אַתָּה יהוה, מְחַיֵּה הַמֵּתִים.","cond":[]},{"kind":"text","text":"אַתָּה קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ וּקְדוֹשִׁים בְּכָל יוֹם יְהַלְלוּךָ סֶּלָה, כִּי אֵל מֶלֶךְ גָּדוֹל וְקָדוֹשׁ אָתָּה.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הָאֵל הַקָּדוֹשׁ.","cond":["noayt"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יהוה, הַמֶּלֶךְ הַקָּדוֹשׁ.","cond":["ayt"]},{"kind":"text","text":"אַתָּה חוֹנֵן לְאָדָם דַּעַת וּמְלַמֵּד לֶאֱנוֹשׁ בִּינָה.","cond":[]},{"kind":"text","text":"חָנֵּנוּ מִאִתְּךָ חָכְמָה בִּינָה וָדָעַת","cond":["noChonantanu"]},{"kind":"special","text":"אַתָּה חוֹנַנְתָּנוּ לְמַדָּע תּוֹרָתֶךָ, וַתְּלַמְּדֵנוּ לַעֲשׂוֹת חֻקֵּי רְצוֹנֶךָ, וַתַּבְדֵּל יהוה אֱלֹהֵינוּ בֵּין קֹדֶשׁ לְחוֹל, בֵּין אוֹר לְחֹשֶׁךְ, בֵּין יִשְׂרָאֵל לָעַמִּים, בֵּין יוֹם הַשְּׁבִיעִי לְשֵׁשֶׁת יְמֵי הַמַּעֲשֶׂה. אָבִינוּ מַלְכֵּנוּ הָחֵל עָלֵינוּ הַיָּמִים הַבָּאִים לִקְרָאתֵנוּ לְשָׁלוֹם, חֲשׂוּכִים מִכָּל חֵטְא וּמְנֻקִּים מִכָּל עָוׂן וּמְדֻבָּקִים בְּיִרְאָתֶךָ.\nוְחָנֵּנוּ מֵאִתְּךָ חָכְמָה בִּינָה וָדָעַת.","cond":["chonantanu"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, חוֹנֵן הַדָּעַת.","cond":[]},{"kind":"text","text":"הֲשִׁיבֵנוּ אָבִינוּ לְתוֹרָתֶךָ, וְקָרְבֵנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶך, וְהַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ. בָּרוּךְ אַתָּה יהוה, הָרוֹצֶה בִּתְשׁוּבָה.","cond":[]},{"kind":"text","text":"סְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ, כִּי אֵל טוֹב וְסַלָּח אָתָּה. בָּרוּךְ אַתָּה יהוה, חַנּוּן הַמַּרְבֶּה לִסְלֹחַ.","cond":[]},{"kind":"text","text":"רְאֵה נָא בְעָנְיֵנוּ, וְרִיבָה רִיבֵנוּ, וּגְאָלֵנוּ גְאֻלָּה שְׁלֵמָה מְהֵרָה לְמַעַן שְׁמֶךָ, כִּי אֵל גּוֹאֵל חָזָק אָתָּה. בָּרוּךְ אַתָּה יהוה, גּוֹאֵל יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"רְפָאֵנוּ יהוה וְנֵרָפֵא, הוֹשִׁיעֵנוּ וְנִוָּשֵׁעָה כִּי תְהִלָּתֵנוּ אָתָּה, וְהַעֲלֵה (אֲרוּכָה וּמַרְפֵּא לְכָל תַּחֲלוּאֵינוּ וּלְכָל מַכְאוֹבֵינוּ) רְפוּאָה שְׁלֵמָה לְכָל מַכּוֹתֵינוּ.","cond":[]},{"kind":"special","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁתִּשְׁלַח מְהֵרָה רְפוּאָה שְׁלֵמָה מִן הַשָּׁמַיִם, רְפוּאַת הַנֶּפֶשׁ וּרְפוּאַת הַגּוּף לַחוֹלֶה (לנקבה: לַחוֹלָה, לרבים: לַחוֹלִים, לרבות: לַחוֹלוֹת):\n:=:=\nבְּתוֹךְ שְׁאָר חוֹלֵי יִשְׂרָאֵל.","cond":["doctor"]},{"kind":"text","text":"כִּי אֵל מֶלֶךְ רוֹפֵא נֶאֱמָן וְרַחֲמָן אָתָּה. בָּרוּךְ אַתָּה יהוה, רוֹפֵא חוֹלֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"בָּרֵך עָלֵינוּ יהוה אֱלֹהֵינוּ אֶת הַשָּׁנָה הַזֹּאת וְאֶת כָּל מִינֵי תְבוּאָתָהּ לְטוֹבָה, וְתֵן","cond":[]},{"kind":"summer","text":"בְּרָכָה","cond":["summerBracha"]},{"kind":"winter","text":"טַל וּמָטָר לִבְרָכָה","cond":["winterBracha"]},{"kind":"text","text":"עַל פְּנֵי הָאֲדָמָה וְשַׂבְּעֵנוּ מִטּוּבָהּ, וּבָרֵךְ שְׁנָתֵנוּ כַּשָּׁנִים הַטּוֹבוֹת לִבְרָכָה. כִּי אֵל טוֹב וּמֵטִיב אַתָּה וּמְבָרֵךְ הַשָּׁנִים. בָּרוּךְ אַתָּה יהוה, מְבָרֵךְ הַשָּׁנִים.","cond":[]},{"kind":"text","text":"תְּקַע בְּשׁוֹפָר גָּדוֹל לְחֵרוּתֵנוּ וְשָׂא נֵס לְקַבֵּץ גָּלֻיּוֹתֵינוּ, וְקַבְּצֵנוּ יַחַד מְהֵרָה מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ לְאַרְצֵנוּ. בָּרוּךְ אַתָּה יהוה, מְקַבֵּץ נִדְחֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"הָשִׁיבָה שׁוֹפְטֵינוּ כְּבָרִאשׁוֹנָה וְיוֹעֲצֵינוּ כְּבַתְּחִלָּה, וְהָסֵר מִמֶּנּוּ יָגוֹן וַאֲנָחָה, וּמְלֹךְ עָלֵינוּ מְהֵרָה אַתָּה יהוה לְבַדְּךָ בְּחֶסֶד וּבְרַחֲמִים, בְּצֶדֶק וּבְמִשְׁפָט.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, מֶלֶךְ אוֹהֵב צְדָקָה וּמִשְׁפָּט.","cond":["noayt"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יהוה, הַמֶּלֶךְ הַמִּשְׁפָּט.","cond":["ayt"]},{"kind":"text","text":"וְלַמַּלְשִׁינִים אַל תְּהִי תִקְוָה, וְכָל הַמִּינִים כְּרֶגַע יֹאבֵדוּ. וְכָל אוֹיְבֵי עַמְּךָ מְהֵרָה יִכָּרֵתוּ, וְהַזֵּדִים מְהֵרָה תְעַקֵּר וּתְשַׁבֵּר וּתְמַגֵּר וּתְכַלֵּם וְתַשְׁפִּילֵם וְתַכְנִיעֵם בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יהוה, שׁוֹבֵר אוֹיְבִים וּמַכְנִיעַ זֵדִים.","cond":[]},{"kind":"text","text":"עַל הַצַּדִּיקִים וְעַל הַחֲסִידִים, וְעַל זִקְנֵי שְׁאֵרִית עַמְּךָ בֵּית יִשְׂרָאֵל, וְעַל פְּלֵיטַת בֵּית סוֹפרֵיהֶם, וְעַל גֵּרֵי הַצֶדֶק וְעָלֵינוּ, יֶהֱמוּ נָא רַחֲמֶיךָ יהוה אֱלֹהֵינוּ, וְתֵן שָׂכָר טוֹב לְכָל הַבּוֹטְחִים בְּשִׁמְךָ בֶּאֱמֶת, וְשִׂים חֶלְקֵנוּ עִמָּהֶם וּלְעוֹלָם לֹא נֵבוֹשׁ כִּי בְךָ בָטָחְנוּ וְעַל חַסְדְּךָ הַגָּדוֹל בֶּאֱמֶת (וּבְתָמִים) נִשְׁעַנּוּ. בָּרוּךְ אַתָּה יהוה, מִשְׁעָן וּמִבְטָח לַצַּדִּיקִים.","cond":[]},{"kind":"text","text":"וְלִירוּשָׁלַיִם עִירְךָ בְּרַחֲמִים תָּשׁוּב וְתִשְׁכֹּן בְּתוֹכָהּ כַּאֲשֶׁר דִּבַּרְתָּ, וּבְנֵה אוֹתָהּ בְּקָרוֹב בְּיָמֵינוּ בִּנְיָן עוֹלָם, וְכִסֵּא דָוִד עַבְדְּךָ מְהֵרָה לְתוֹכָהּ תָּכִין. בָּרוּךְ אַתָּה יהוה, בּוֹנֵה יְרוּשָׁלָיִם.","cond":[]},{"kind":"text","text":"אֶת צֶמַח דָּוִד עַבְדְּךָ מְהֵרָה תַצְמִיחַ, וְקַרְנוֹ תָּרוּם בִּישׁוּעָתֶךָ, כִּי לִישׁוּעָתְךָ קִוִּינוּ כָּל הַיּוֹם (וּמְצַפִּים לִישׁוּעָה). בָּרוּךְ אַתָּה יהוה, מַצְמִיחַ קֶרֶן יְשׁוּעָה.","cond":[]},{"kind":"text","text":"אָב הָרַחֲמָן, שְׁמַע קוֹלֵנוּ יהוה אֱלֹהֵינוּ, חוּס וְרַחֵם עָלֵינוּ, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ, כִּי אֵל שׁוֹמֵעַ תְּפִלּוֹת וְתַחֲנוּנִים אָתָּה, וּמִלְּפָנֶיךָ מַלְכֵּנוּ, רֵיקָם אַל תְּשִׁיבֵנוּ. חָנֵּנוּ וַעֲנֵנוּ וּשְׁמַע תְּפִלָּתֵנוּ.","cond":[]},{"kind":"special","text":"וַעֲנֵנוּ בּוֹרֵא עוֹלָם בְּמִדַּת הָרַחֲמִים, בּוֹחֵר בְּעַמּוֹ יִשְׂרָאֵל לְהוֹדִיעַ גָדְלוֹ וְהַדְרַת כְּבוֹדוֹ, שׁוֹמֵעַ תְּפִלָּה תֵּן טַל וּמָטָר עַל פְּנֵי הָאֲדָמָה, וְתַשְׂבִּיעַ אֶת הָעוֹלָם כֻּלּוֹ מִטּוּבֶךָ, וּמַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ וּמֵעֹשֶׁר מַתְּנַת יָדֶךָ, שְׁמוֹר וְהַצֵּל שָׁנָה זוֹ מִכָּל דָּבָר רָע, וּמִכָּל מִינִי מַשְׁחִית, וּמִכָּל מִינֵי פֻּרְעָנֻיּוֹת, וַעֲשֵׂה לָהּ תִּקְוָה וְאַחֲרִית שָׁלוֹם, חוּס וְרַחֵם עָלֵינוּ וְעַל כָּל תְּבוּאָתֵנוּ וּפֵרוֹתֵינוּ, וּבָרְכֵנוּ בְּגִשְׁמֵי בְרָכָה וְנִזְכֶּה לְחַיִּים וָשֹׂבַע וְשָׁלוֹם, כַּשָּׁנִים הַטּוֹבוֹת, וְהָסֵר מִמֶּנּוּ דֶּבֶר וְחֶרֶב וְרָעָב, וְחַיָּה רָעָה וּשְׁבִי וּבִזָּה, וְיֵצֶר הָרָע וָחֳלָיִם רָעִים וְקָשִׁים, וּמְאוֹרָעוֹת רָעִים וְקָשִׁים, וּגְזֹר עָלֵינוּ גְּזֵרוֹת טוֹבוֹת מִלְּפָנֶיךָ, וְיִגֹּלוּ רָחֲמֶיךָ עַל מִדּוֹתֶיךָ, וְתִתְנַהֵג עִם בָּנֶיךָ בְּמִדַּת הָרַחֲמִים, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ.","cond":["vaanenu"]},{"kind":"text","text":"כִּי אַתָּה שׁוֹמֵעַ תְּפִלַּת כָּל פֶּה. בָּרוּךְ אַתָּה יהוה, שׁוֹמֵעַ תְּפִלָּה.","cond":[]},{"kind":"text","text":"רְצֵה יהוה אֱלֹהֵינוּ בְּעַמְּךָ יִשְׂרָאֵל וְלִתְפִלָּתָם שְׁעֵה, וְהָשֵׁב אֶת הָעֲבוֹדָה לִדְבִיר בֵּיתֶךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם, מְהֵרָה בְּאַהֲבָה תְקַבֵּל בְּרָצוֹן. וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּךָ.","cond":[]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּיעַ וְיֵרָאֶה וְיֵרָצֶה, וְיִשָּׁמַע וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵנוּ וּפִקְדוֹנֵנו וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךְ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָָל עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶיךָ, לִפְלֵטָה, לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["rh"]},{"kind":"special","text":"רֹאשׁ הַחֹדֶשׁ הַזֶּה.","cond":["rh"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ, וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["rh"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּיעַ וְיֵרָאֶה וְיֵרָצֶה, וְיִשָּׁמַע וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵנוּ וּפִקְדוֹנֵנו וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךְ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָָל עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶיךָ, לִפְלֵטָה, לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["sucot"]},{"kind":"special","text":"חַג הַסֻּכּוֹת הַזֶּה.","cond":["sucot"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ, וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["sucot"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּיעַ וְיֵרָאֶה וְיֵרָצֶה, וְיִשָּׁמַע וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵנוּ וּפִקְדוֹנֵנו וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךְ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָָל עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶיךָ, לִפְלֵטָה, לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["pesach"]},{"kind":"special","text":"חַג הַמַּצּוֹת הַזֶּה.","cond":["pesach"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ, וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["pesach"]},{"kind":"text","text":"וְתֶחֱזֶינָה עֵינֵינוּ בְּשׁוּבְךָ לְצִיּוֹן בְּרַחֲמִים. בָּרוּךְ אַתָּה יהוה, הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן.","cond":[]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שָׁאַתָּה הוּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ לְעוֹלָם וָעֵד. צוּר חַיֵּינוּ, מָגֵן יִשְׁעֵנוּ אַתָּה הוּא לְדוֹר וָדוֹר. נוֹדֶה לְּךָ וּנְסַפֵּר תְּהִלָּתֶךָ עַל חַיֵּינוּ הַמְּסוּרִים בְּיָדֶךָ, וְעַל נִשְׁמוֹתֵינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּיךָ שֶׁבְּכָל יוֹם עִמָּנוּ, וְעַל נִפְלְאוֹתֶיךָ וְטוֹבוֹתֶיךָ שֶׁבְּכָל עֵת, עֶרֶב וָבֹקֶר וְצָהֳרָיִם. הַטּוֹב כִּי לֹא כָלוּ רַחֲמֶיךָ, וְהַמְרַחֵם כִּי לֹא תַמּוּ חֲסָדֶיךָ, כִּי מֵעוֹלָם קִוִּינוּ לָךְ.","cond":[]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מַתִּתְיָהוּ בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְהַשְׁכִּיחָם תּוֹרָתֶךָ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנֶךָ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּטְמֵאִים בְּיַד טְהוֹרִים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, וּלְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמֶךָ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כֵּן בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ לְהוֹדוֹת וּלְהַלֵּל לְשִׁמְךָ הַגָּדוֹל. (נ\"א: וְקָבְעוּ שְׁמוֹנַת יָמִים אֵלּוּ בְּהַלֵּל וּבְהוֹדָאָה וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה.)","cond":["chanuka"]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים, מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ, וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ, וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְּרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ (, וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה).","cond":["purim"]},{"kind":"text","text":"וְעַל כֻּלָּם יִתְבָּרַךְ וְיִתְרוֹמַם וְיִתְנַשֵּׂא שִׁמְךָ מַלְכֵּנוּ תָּמִיד לְעוֹלָם וָעֶד.","cond":[]},{"kind":"special","text":"וּכְתֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶךָ.","cond":["ayt"]},{"kind":"text","text":"וְכֹל הַחַיִּים יוֹדוּךָ סֶלָה, וִיהַלְלוּ וִיבָרְכוּ אֶת שִׁמְךָ הַגָּדוֹל בֶּאֱמֶת לְעוֹלָם כִּי טוֹב, הָאֵל יְשׁוּעָתֵנוּ וְעֶזְרָתֵנוּ סֶלָה, הָאֵל הַטּוֹב. בָּרוּך אַתָּה יהוה, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת.","cond":[]},{"kind":"text","text":"שִׂים שָׁלוֹם טוֹבָה וּבְרָכָה, חַיִּים חֵן וָחֶסֶד וְרַחֲמִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל עַמֶּךָ. בָּרְכֵנוּ אָבִינוּ כֻּלָּנוּ כְּאֶחָד (יַחַד) בְּאוֹר פָּנֶיךָ, כִּי בְאוֹר פָּנֶיךָ נָתַתָּ לָּנוּ יהוה אֱלֹהֵינוּ תּוֹרַת חַיִּים וְאַהֲבַת חֶסֶד, וּצְדָקָה וּבְרָכָה וְרַחֲמִים וְחַיִּים וְשָׁלוֹם. וְטוֹב יִהְיֶה בְעֵינֶיךָ לְבָרְכֵנוּ וּלְבָרֵךְ אֶת כָּל עַמְּךָ יִשְׂרָאֵל בְּכָל עֵת וּבְכָל שָׁעָה בִּשְׁלוֹמֶךָ (בְּרֹב עֹז וְשָׁלוֹם).","cond":[]},{"kind":"special","text":"בְּסֵפֶר חַיִּים, בְּרָכָה וְשָׁלוֹם, וּפַרְנָסָה טוֹבָה, וּגְזֵרוֹת טוֹבוֹת, יְשׁוּעוֹת וְנֶחָמוֹת, נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ, אֲנַחְנוּ וְכָל עַמְּךָ בֵּית יִשְׂרָאֵל, לְחַיִּים טוֹבִים וּלְשָׁלוֹם.","cond":["ayt"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, הַמְבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם.","cond":[]},{"kind":"text","text":"יִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ. יהוה צוּרִי וְגוֹאֲלִי:\nאֱלֹהַי, נְצֹר לְשׁוֹנִי מֵרָע וּשְׂפָתַי מִדַּבֵּר מִרְמָה, וְלִמְקַלְלַי נַפְשִׁי תִדֹּם, וְנַפְשִׁי כֶּעָפָר לַכֹּל תִּהְיֶה. פְּתַח לִבִּי בְּתוֹרָתֶךָ, וְאַחֲרֵי מִצְוׂתֶיךָ תִּרְדֹף נַפְשִׁי. וְכָל הַקָּמִים וְהַחוֹשְׁבִים עָלַי לְרָעָה, מְהֵרָה הָפֵר עֲצָתָם וְקַלְקֵל מַחֲשַׁבְתָּם.\n(יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁלֹּא תַעֲלֶה קִנְאַת אָדָם עָלַי וְלֹא קִנְאָתִי עַל אֲחֵרִים, וְשֶׁלֹּא אֶכְעוֹס הַיּוֹם וְשֶׁלֹּא אַכְעִיסֶךָ. וְתַצִּילֵנִי מִיֵּצֶר הָרָע, וְתֵן בְּלִבִּי הַכְנָעָה וַעֲנָוָה. מַלְכֵּנוּ וֵאלֹהֵינוּ אֱלוֹהַּ כָּל בָּשָׂר, יַחֵד שִׁמְךָ בְּעוֹלָמֶךָ, בְּנֵה עִירֶךָ, יַסֵּד בֵּיתֶךָ וְשַׁכְלֵל הֵיכָלֶךָ, וְקַבֵּץ קִבּוּץ גָלֻיּוֹת וּפְדֵה צֹאנֶךָ וְשַׂמַּח עָדָתֶךָ.)\nעֲשֵׂה לְמַעַן שְׁמֶךָ, עֲשֵׂה לְמַעַן יְמִינֶךָ, עֲשֵׂה לְמַעַן תּוֹרָתֶךָ, עֲשֵׂה לְמַעַן קְדֻשָּׁתֶךָ. לְמַעַן יֵחָלְצוּן יְדִידֶיךָ הוֹשִׁיעָה יְמִינְךָ וַעֲנֵנִי:\nיִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:","cond":[]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁיִּבָּנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵינוּ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתֶךָ, וְשָׁם נַעֲבָדְךָ בְּיִרְאָה כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמוֹנִיּוֹת. וְעָרְבָה לַיהוה מִנְחַת יְהוּדָה וִירוּשָׁלָיִם כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמֹנִיּוֹת:","cond":[]},{"kind":"instruction","text":"חצי קדיש","cond":["kadosh"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":["kadosh"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["kadosh","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["kadosh","ayt"]},{"kind":"header","text":"ויהי נעם","cond":["kadosh","sun"]},{"kind":"text","text":"וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ: יֹשֵׁב בְּסֵתֶר עֶלְיוֹן בְּצֵל שַׁדַּי יִתְלוֹנָן: אֹמַר לַיהוה מַחְסִי וּמְצוּדָתִי, אֱלֹהַי אֶבְטַח בּוֹ: כִּי הוּא יַצִּילְךָ מִפַּח יָקוּשׁ מִדֶּבֶר הַוּוֹת: בְּאֶבְרָתוֹ יָסֶךְ לָךְ וְתַחַת כְּנָפָיו תֶּחְסֶה, צִנָּה וְסֹחֵרָה אֲמִתּוֹ: לֹא תִירָא מִפַּחַד לָיְלָה, מֵחֵץ יָעוּף יוֹמָם: מִדֶּבֶר בָּאֹפֶל יַהֲלֹךְ, מִקֶּטֶב יָשׁוּד צָהֳרָיִם: יִפֹּל מִצִּדְּךָ אֶלֶף וּרְבָבָה מִימִינֶךָ, אֵלֶיךָ לֹא יִגָּשׁ: רַק בְּעֵינֶיךָ תַבִּיט, וְשִׁלֻּמַת רְשָׁעִים תִּרְאֶה: כִּי אַתָּה יהוה מַחְסִי, עֶלְיוֹן שַׂמְתָּ מְעוֹנֶךָ: לֹא תְאֻנֶּה אֵלֶיךָ רָעָה, וְנֶגַע לֹא יִקְרַב בְּאָהֳלֶךָ: כִּי מַלְאָכָיו יְצַוֶּה לָּךְ, לִשְׁמָרְךָ בְּכָל דְּרָכֶיךָ: עַל כַּפַּיִם יִשָּׂאוּנְךָ, פֶּן תִּגֹּף בָּאֶבֶן רַגְלֶךָ: עַל שַׁחַל וָפֶתֶן תִּדְרֹךְ, תִּרְמֹס כְּפִיר וְתַנִּין: כִּי בִי חָשַׁק וַאֲפַלְּטֵהוּ, אֲשַׂגְּבֵהוּ כִּי יָדַע שְׁמִי: יִקְרָאֵנִי וְאֶעֱנֵהוּ, עִמּוֹ אָנֹכִי בְצָרָה, אֲחַלְּצֵהוּ וַאֲכַבְּדֵהוּ: אֹרֶךְ יָמִים אַשְׂבִּיעֵהוּ, וְאַרְאֵהוּ בִּישׁוּעָתִי: אֹרֶךְ יָמִים אַשְׂבִּיעֵהוּ, וְאַרְאֵהוּ בִּישׁוּעָתִי:","cond":["kadosh","sun"]},{"kind":"header","text":"ואתה קדוש","cond":["kadosh"]},{"kind":"text","text":"וְאַתָּה קָדוֹשׁ יוֹשֵׁב תְּהִלּוֹת יִשְׂרָאֵל: וְקָרָא זֶה אֶל זֶה וְאָמַר: קָדוֹשׁ, קָדוֹשׁ, קָדוֹשׁ יהוה צְבָאוֹת, מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ: וּמְקַבְּלִין דֵּין מִן דֵּין וְאָמְרִין: קַדִּישׁ בִּשְׁמֵי מֵרוֹמַא עִלָאַה בֵּית שְׁכִינְתֵּהּ, קַדִּישׁ עַל אַרְעָא עוֹבַד גְּבוּרְתֵּהּ, קַדִּישׁ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא, יהוה צְבָאוֹת מַלְיָא כָל אַרְעָא זִיו יְקָרֵהּ. וַתִּשָּׂאֵנִי רוּחַ, וָאֶשְׁמַע אַחֲרַי קוֹל רַעַשׁ גָּדוֹל: בָּרוּךְ כְּבוֹד יהוה מִמְּקוֹמוֹ: וּנְטָלַתְנִי רוּחָא, וּשְׁמָעִית בַּתְרַי קַל זִיעַ שַׂגִּיא דִמְשַׁבְּחִין וְאָמְרִין: בְּרִיךְ יְקָרָא דַיהוה מֵאֲתָר בֵּית שְׁכִינְתֵּהּ. יהוה יִמְלֹךְ לְעוֹלָם וָעֶד: יהוה מַלְכוּתֵיהּ קָאֵים לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\n\nיהוה אֱלֹהֵי אַבְרָהָם יִצְחָק וְיִשְׂרָאֵל אֲבוֹתֵינוּ, שָׁמְרָה זֹּאת לְעוֹלָם, לְיֵצֶר מַחְשְׁבוֹת לְבַב עַמֶּךָ, וְהָכֵן לְבָבָם אֵלֶיךָ: וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית, וְהִרְבָּה לְהָשִׁיב אַפּוֹ, וְלֹא יָעִיר כָּל חֲמָתוֹ: כִּי אַתָּה יהוה טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קוֹרְאֶיךָ: צִדְקָתְךָ צֶּדֶק לְעוֹלָם, וְתוֹרָתְךָ אֱמֶת: תִּתֵּן אֱמֶת לְיַעֲקֹב, חֶסֶד לְאַבְרָהָם, אֲשֶׁר נִשְׁבַּעְתָּ לַאֲבֹתֵינוּ מִימֵי קֶדֶם: בָּרוּךְ אֲדֹנָי יוֹם יוֹם, יַעֲמָס לָנוּ הָאֵל יְשׁוּעָתֵנוּ, סֶלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב, סֶלָה: יהוה צְבָאוֹת אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ: בָּרוּךְ הוּא אֱלֹהֵינוּ שֶׁבְּרָאָנוּ לִכְבוֹדוֹ, וְהִבְדִּילָנוּ מִן הַתּוֹעִים, וְנָתַן לָנוּ תּוֹרַת אֱמֶת, וְחַיֵּי עוֹלָם נָטַע בְּתוֹכֵנוּ. הוּא יִפְתַּח לִבֵּנוּ בְּתוֹרָתוֹ, וְיָשֵׂם בְּלִבֵּנוּ אַהֲבָתוֹ וְיִרְאָתוֹ וְלַעֲשׂוֹת רְצוֹנוֹ וּלְעָבְדוֹ בְּלֵבָב שָׁלֵם. לְמַעַן לֹא נִיגַע לָרִיק, וְלֹא נֵלֵד לַבֶּהָלָה. יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁנִּשְׁמֹר חֻקֶּיךָ בָּעוֹלָם הַזֶּה, וְנִזְכֶּה וְנִחְיֶה וְנִרְאֶה וְנִירַשׁ טוֹבָה וּבְרָכָה לִשְׁנֵי יְמוֹת הַמָּשִׁיחַ וּלְחַיֵּי הָעוֹלָם הַבָּא. לְמַעַן יְזַמֶּרְךָ כָבוֹד וְלֹא יִדֹּם, יהוה אֱלֹהַי לְעוֹלָם אוֹדֶךָּ: בָּרוּךְ הַגֶּבֶר אֲשֶׁר יִבְטַח בַּיהוה, וְהָיָה יהוה מִבְטַחוֹ: בִּטְחוּ בַיהוה עֲדֵי עַד, כִּי בְּיָהּ יהוה צוּר עוֹלָמִים: וְיִבְטְחוּ בְךָ יוֹדְעֵי שְׁמֶךָ, כִּי לֹא עָזַבְתָּ דֹּרְשֶׁיךָ יהוה: יהוה חָפֵץ לְמַעַן צִדְקוֹ, יַגְדִּיל תּורָה וְיַאְדִּיר: יהוה אֲדֹנֵינוּ, מָה אַדִּיר שִׁמְךָ בְּכָל הָאָרֶץ: חִזְקוּ וְיַאֲמֵץ לְבַבְכֶם כָּל הַמְיַחֲלִים לַיהוה:","cond":["kadosh"]},{"kind":"instruction","text":"קדיש תתקבל","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":[]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"תִּתְקַבַּל צְלוֹתְהוֹן וּבָעוּתְהוֹן דְּכָל בֵּית יִשְׂרָאֵל קֳדָם אֲבוּהוֹן דִּי בִשְׁמַיָּא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"header","text":"המשך תפילת יום העצמאות","cond":["yerushalayim"]},{"kind":"instruction","text":"פותחים את הארון\n\nהש\"ץ אומר והקהל עונה אחריו:","cond":["yerushalayim"]},{"kind":"text","text":"שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:\n\nיהוה הוּא הָאֱלֹהִים: יהוה הוּא הָאֱלֹהִים: יהוה הוּא הָאֱלֹהִים:","cond":["yerushalayim"]},{"kind":"instruction","text":"הש\"ץ אומר והקהל חוזר אחריו:","cond":["yerushalayim"]},{"kind":"text","text":"מִי שֶׁעָשָׂה נִסִּים לַאֲבוֹתֵינוּ וְלָנוּ וּגְאָלָנוּ מֵעַבְדּוּת לְחֵרוּת, הוּא יִגְאָלֵנוּ גְאֻלָּה שְׁלֵמָה בְּקָרוֹב, וִיקַבֵּץ נִדָּחֵינוּ מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ, חֲבֵרִים כָּל יִשְׂרָאֵל, וְנֹאמַר אָמֵן.","cond":["yerushalayim"]},{"kind":"instruction","text":"הש\"ץ אומר:","cond":["yerushalayim"]},{"kind":"text","text":"וְכִי-תָבֹאוּ מִלְחָמָה בְּאַרְצְכֶם, עַל-הַצַּר הַצֹּרֵר אֶתְכֶם, וַהֲרֵעֹתֶם בַּחֲצֹצְרֹת, וְנִזְכַּרְתֶּם לִפְנֵי יהוה אֱלֹהֵיכֶם וְנוֹשַׁעְתֶּם מֵאֹיְבֵיכֶם: וּבְיוֹם שִׂמְחַתְכֶם וּבְמוֹעֲדֵיכֶם וּבְרָאשֵׁי חָדְשֵׁיכֶם וּתְקַעְתֶּם בַּחֲצֹצְרֹת עַל עֹלֹתֵיכֶם וְעַל זִבְחֵי שַׁלְמֵיכֶם וְהָיוּ לָכֶם לְזִכָּרוֹן לִפְנֵי אֱלֹהֵיכֶם, אֲנִי יהוה אֱלֹהֵיכֶם:","cond":["yerushalayim"]},{"kind":"instruction","text":"תוקעים תקיעה גדולה ואומרים בקול רם:","cond":["yerushalayim"]},{"kind":"text","text":"לַשָּׁנָה הַבָּאָה בִּירוּשָׁלַיִם הַבְּנוּיָה.","cond":["yerushalayim"]},{"kind":"instruction","text":"(כל הקהל אומר","cond":["yerushalayim"]},{"kind":"text","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁכְּשֵׁם שֶׁזָּכִינוּ לְאַתְחַלְתָּא דִגְאֻלָּה, כֵּן נִזְכֶּה לִשְׁמֹעַ קוֹל שׁוֹפָרוֹ שֶׁל מָשִׁיחַ בִּמְהֵרָה בְיָמֵינוּ.)","cond":["yerushalayim"]},{"kind":"instruction","text":"ושרים במנגינת התקוה:","cond":["yerushalayim"]},{"kind":"text","text":"שִׁיר הַמַּעֲלוֹת בְּשׁוּב יהוה אֶת שִׁיבַת צִיּוֹן, הָיִינוּ כְּחֹלְמִים: אָז יִמָּלֵא שְׂחוֹק פִּינוּ וּלְשׁוֹנֵנוּ רִנָּה, אָז יֹאמְרוּ בַגּוֹיִם הִגְדִּיל יהוה לַעֲשׂוֹת עִם אֵלֶּה: הִגְדִּיל יהוה לַעֲשׂוֹת עִמָּנוּ, הָיִינוּ שְׂמֵחִים: שׁוּבָה יהוה אֶת שְׁבִיתֵנוּ כַּאֲפִיקִים בַּנֶּגֶב: הַזֹּרְעִים בְּדִמְעָה בְּרִנָּה יִקְצֹרוּ: הָלוֹךְ יֵלֵךְ וּבָכֹה נֹשֵׂא מֶשֶׁךְ הַזָּרַע, בֹּא יָבוֹא בְרִנָּה נֹשֵׂא אֲלֻמֹּתָיו:","cond":["yerushalayim"]},{"kind":"instruction","text":"מברך לאור הנר:","cond":["tishaaBeav","sun"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא מְאוֹרֵי הָאֵשׁ.","cond":["tishaaBeav","sun"]},{"kind":"header","text":"מגילת איכה","cond":["tishaaBeav"]},{"kind":"instruction","text":"מגילת איכה\n\n\nפרק א'","cond":["tishaaBeav"]},{"kind":"text","text":"אֵיכָה יָשְׁבָה בָדָד הָעִיר רַבָּתִי עָם הָיְתָה כְּאַלְמָנָה, רַבָּתִי בַגּוֹיִם, שָׂרָתִי בַּמְּדִינוֹת, הָיְתָה לָמַס: בָּכוֹ תִבְכֶּה בַּלַּיְלָה וְדִמְעָתָהּ עַל לֶחֱיָהּ, אֵין לָהּ מְנַחֵם מִכָּל אֹהֲבֶיהָ, כָּל רֵעֶיהָ בָּגְדוּ בָהּ, הָיוּ לָהּ לְאֹיְבִים: גָּלְתָה יְהוּדָה מֵעֹנִי וּמֵרֹב עֲבֹדָה, הִיא יָשְׁבָה בַגּוֹיִם, לֹא מָצְאָה מָנוֹחַ, כָּל רֹדְפֶיהָ הִשִּׂיגוּהָ בֵּין הַמְּצָרִים: דַּרְכֵי צִיּוֹן אֲבֵלוֹת מִבְּלִי בָּאֵי מוֹעֵד, כָּל שְׁעָרֶיהָ שׁוֹמֵמִין, כֹּהֲנֶיהָ נֶאֱנָחִים, בְּתוּלֹתֶיהָ נּוּגוֹת וְהִיא מַר לָהּ: הָיוּ צָרֶיהָ לְרֹאשׁ אֹיְבֶיהָ שָׁלוּ, כִּי יהוה הוֹגָהּ עַל רֹב פְּשָׁעֶיהָ, עוֹלָלֶיהָ הָלְכוּ שְׁבִי לִפְנֵי צָר: וַיֵּצֵא מִבַּת צִיּוֹן כָּל הֲדָרָהּ, הָיוּ שָׂרֶיהָ כְּאַיָּלִים לֹא מָצְאוּ מִרְעֶה, וַיֵּלְכוּ בְלֹא כֹחַ לִפְנֵי רוֹדֵף: זָכְרָה יְרוּשָׁלַיִם יְמֵי עָנְיָהּ וּמְרוּדֶיהָ, כֹּל מַחֲמֻדֶיהָ אֲשֶׁר הָיוּ מִימֵי קֶדֶם, בִּנְפֹל עַמָּהּ בְּיַד צָר וְאֵין עוֹזֵר לָהּ, רָאוּהָ צָרִים, שָׂחֲקוּ עַל מִשְׁבַּתֶּהָ: חֵטְא חָטְאָה יְרוּשָׁלַיִם, עַל כֵּן לְנִידָה הָיָתָה, כָּל מְכַבְּדֶיהָ הִזִּילוּהָ כִּי רָאוּ עֶרְוָתָהּ, גַּם הִיא נֶאֶנְחָה וַתָּשָׁב אָחוֹר: טֻמְאָתָהּ בְּשׁוּלֶיהָ, לֹא זָכְרָה אַחֲרִיתָהּ, וַתֵּרֶד פְּלָאִים, אֵין מְנַחֵם לָהּ, רְאֵה יהוה אֶת עָנְיִי כִּי הִגְדִּיל אוֹיֵב: יָדוֹ פָּרַשׂ צָר עַל כָּל מַחֲמַדֶּיהָ, כִּי רָאֲתָה גוֹיִם בָּאוּ מִקְדָּשָׁהּ, אֲשֶׁר צִוִּיתָה לֹא יָבֹאוּ בַקָּהָל לָךְ: כָּל עַמָּהּ נֶאֱנָחִים מְבַקְשִׁים לֶחֶם, נָתְנוּ מַחֲמַדֵּיהֶם בְּאֹכֶל לְהָשִׁיב נָפֶשׁ, רְאֵה יהוה וְהַבִּיטָה כִּי הָיִיתִי זוֹלֵלָה: לוֹא אֲלֵיכֶם כָּל עֹבְרֵי דֶרֶךְ, הַבִּיטוּ וּרְאוּ אִם יֵשׁ מַכְאוֹב כְּמַכְאֹבִי אֲשֶׁר עוֹלַל לִי, אֲשֶׁר הוֹגָה יהוה בְּיוֹם חֲרוֹן אַפּוֹ: מִמָּרוֹם שָׁלַח אֵשׁ בְּעַצְמֹתַי וַיִּרְדֶּנָּה, פָּרַשׂ רֶשֶׁת לְרַגְלַי הֱשִׁיבַנִי אָחוֹר, נְתָנַנִי שֹׁמֵמָה כָּל הַיּוֹם דָּוָה: נִשְׂקַד עֹל פְּשָׁעַי בְּיָדוֹ, יִשְׂתָּרְגוּ, עָלוּ עַל צַוָּארִי הִכְשִׁיל כֹּחִי, נְתָנַנִי אֲדֹנָי בִּידֵי לֹא אוּכַל קוּם: סִלָּה כָל אַבִּירַי אֲדֹנָי בְּקִרְבִּי, קָרָא עָלַי מוֹעֵד לִשְׁבֹּר בַּחוּרָי, גַּת דָּרַךְ אֲדֹנָי לִבְתוּלַת בַּת יְהוּדָה: עַל אֵלֶּה אֲנִי בוֹכִיָּה, עֵינִי עֵינִי יֹרְדָה מַּיִם, כִּי רָחַק מִמֶּנִּי מְנַחֵם מֵשִׁיב נַפְשִׁי, הָיוּ בָנַי שׁוֹמֵמִים כִּי גָבַר אוֹיֵב: פֵּרְשָׂה צִיּוֹן בְּיָדֶיהָ, אֵין מְנַחֵם לָהּ, צִוָּה יהוה לְיַעֲקֹב סְבִיבָיו צָרָיו, הָיְתָה יְרוּשָׁלַיִם לְנִדָּה בֵּינֵיהֶם: צַדִּיק הוּא יהוה כִּי פִיהוּ מָרִיתִי, שִׁמְעוּ נָא כָל הָעַמִּים וּרְאוּ מַכְאֹבִי, בְּתוּלֹתַי וּבַחוּרַי הָלְכוּ בַשֶּׁבִי: קָרָאתִי לַמְאַהֲבַי הֵמָּה רִמּוּנִי, כֹּהֲנַי וּזְקֵנַי בָּעִיר גָּוָעוּ, כִּי בִקְשׁוּ אֹכֶל לָמוֹ וְיָשִׁיבוּ אֶת נַפְשָׁם: רְאֵה יהוה כִּי צַר לִי מֵעַי חֳמַרְמָרוּ, נֶהְפַּךְ לִבִּי בְּקִרְבִּי כִּי מָרוֹ מָרִיתִי, מִחוּץ שִׁכְּלָה חֶרֶב, בַּבַּיִת כַּמָּוֶת: שָׁמְעוּ כִּי נֶאֱנָחָה אָנִי, אֵין מְנַחֵם לִי, כָּל אֹיְבַי שָׁמְעוּ רָעָתִי שָׂשׂוּ כִּי אַתָּה עָשִׂיתָ, הֵבֵאתָ יוֹם קָרָאתָ וְיִהְיוּ כָמוֹנִי: תָּבֹא כָל רָעָתָם לְפָנֶיךָ וְעוֹלֵל לָמוֹ, כַּאֲשֶׁר עוֹלַלְתָּ לִי עַל כָּל פְּשָׁעָי, כִּי רַבּוֹת אַנְחֹתַי וְלִבִּי דַוָּי:","cond":["tishaaBeav"]},{"kind":"instruction","text":"פרק ב'","cond":["tishaaBeav"]},{"kind":"text","text":"אֵיכָה יָעִיב בְּאַפּוֹ אֲדֹנָי אֶת בַּת צִיּוֹן, הִשְׁלִיךְ מִשָּׁמַיִם אֶרֶץ, תִּפְאֶרֶת יִשְׂרָאֵל, וְלֹא זָכַר הֲדֹם רַגְלָיו בְּיוֹם אַפּוֹ: בִּלַּע אֲדֹנָי וְלֹא חָמַל אֵת כָּל נְאוֹת יַעֲקֹב, הָרַס בְּעֶבְרָתוֹ מִבְצְרֵי בַת יְהוּדָה הִגִּיעַ לָאָרֶץ, חִלֵּל מַמְלָכָה וְשָׂרֶיהָ: גָּדַע בָּחֳרִי אַף כֹּל קֶרֶן יִשְׂרָאֵל, הֵשִׁיב אָחוֹר יְמִינוֹ מִפְּנֵי אוֹיֵב, וַיִּבְעַר בְּיַעֲקֹב כְּאֵשׁ לֶהָבָה, אָכְלָה סָבִיב: דָּרַךְ קַשְׁתּוֹ כְּאוֹיֵב, נִצָּב יְמִינוֹ כְּצָר, וַיַּהֲרֹג כֹּל מַחֲמַדֵּי עָיִן, בְּאֹהֶל בַּת צִיּוֹן שָׁפַךְ כָּאֵשׁ חֲמָתוֹ: הָיָה אֲדֹנָי כְּאוֹיֵב, בִּלַּע יִשְׂרָאֵל, בִּלַּע כָּל אַרְמְנוֹתֶיהָ שִׁחֵת מִבְצָרָיו, וַיֶּרֶב בְּבַת יְהוּדָה תַּאֲנִיָּה וַאֲנִיָּה: וַיַּחְמֹס כַּגַּן שֻׂכּוֹ שִׁחֵת מוֹעֲדוֹ, שִׁכַּח יהוה בְּצִיּוֹן מוֹעֵד וְשַׁבָּת, וַיִּנְאַץ בְּזַעַם אַפּוֹ מֶלֶךְ וְכֹהֵן: זָנַח אֲדֹנָי מִזְבְּחוֹ, נִאֵר מִקְדָּשׁוֹ, הִסְגִּיר בְּיַד אוֹיֵב חוֹמֹת אַרְמְנוֹתֶיהָ, קוֹל נָתְנוּ בְּבֵית יהוה כְּיוֹם מוֹעֵד: חָשַׁב יהוה לְהַשְׁחִית חוֹמַת בַּת צִיּוֹן, נָטָה קָו לֹא הֵשִׁיב יָדוֹ מִבַּלֵּעַ, וַיַּאֲבֶל חֵל וְחוֹמָה יַחְדָּו אֻמְלָלוּ: טָבְעוּ בָאָרֶץ שְׁעָרֶיהָ, אִבַּד וְשִׁבַּר בְּרִיחֶיהָ, מַלְכָּהּ וְשָׂרֶיהָ בַגּוֹיִם אֵין תּוֹרָה, גַּם נְבִיאֶיהָ לֹא מָצְאוּ חָזוֹן מֵיהוה: יֵשְׁבוּ לָאָרֶץ יִדְּמוּ זִקְנֵי בַת צִיּוֹן, הֶעֱלוּ עָפָר עַל רֹאשָׁם, חָגְרוּ שַׂקִּים, הוֹרִידוּ לָאָרֶץ רֹאשָׁן בְּתוּלֹת יְרוּשָׁלַיִם: כָּלוּ בַדְּמָעוֹת עֵינַי חֳמַרְמְרוּ מֵעַי, נִשְׁפַּךְ לָאָרֶץ כְּבֵדִי עַל שֶׁבֶר בַּת עַמִּי, בֵּעָטֵף עוֹלֵל וְיוֹנֵק בִּרְחֹבוֹת קִרְיָה: לְאִמֹּתָם יֹאמְרוּ אַיֵּה דָּגָן וָיָיִן, בְּהִתְעַטְּפָם כֶּחָלָל בִּרְחֹבוֹת עִיר, בְּהִשְׁתַּפֵּךְ נַפְשָׁם אֶל חֵיק אִמֹּתָם: מָה אֲעִידֵךְ מָה אֲדַמֶּה לָּךְ, הַבַּת יְרוּשָׁלַיִם, מָה אַשְׁוֶה לָּךְ וַאֲנַחֲמֵךְ בְּתוּלַת בַּת צִיּוֹן, כִּי גָדוֹל כַּיָּם שִׁבְרֵךְ מִי יִרְפָּא לָךְ: נְבִיאַיִךְ חָזוּ לָךְ שָׁוְא וְתָפֵל, וְלֹא גִלּוּ עַל עֲוׂנֵךְ לְהָשִׁיב שְׁבוּתֵךְ, וַיֶּחֱזוּ לָךְ מַשְׂאוֹת שָׁוְא וּמַדּוּחִים: סָפְקוּ עָלַיִךְ כַּפַּיִם כָּל עֹבְרֵי דֶרֶךְ, שָׁרְקוּ וַיָּנִעוּ רֹאשָׁם עַל בַּת יְרוּשָׁלָיִם, הֲזֹאת הָעִיר שֶׁיֹּאמְרוּ כְּלִילַת יֹפִי, מָשׂוֹשׂ לְכָל הָאָרֶץ: פָּצוּ עָלַיִךְ פִּיהֶם כָּל אוֹיְבַיִךְ, שָׁרְקוּ וַיַּחַרְקוּ שֵׁן, אָמְרוּ בִּלָּעְנוּ, אַךְ זֶה הַיּוֹם שֶׁקִּוִּינֻהוּ מָצָאנוּ רָאִינוּ: עָשָׂה יהוה אֲשֶׁר זָמָם, בִּצַּע אֶמְרָתוֹ אֲשֶׁר צִוָּה מִימֵי קֶדֶם, הָרַס וְלֹא חָמָל, וַיְשַׂמַּח עָלַיִךְ אוֹיֵב, הֵרִים קֶרֶן צָרָיִךְ: צָעַק לִבָּם אֶל אֲדֹנָי, חוֹמַת בַּת צִיּוֹן הוֹרִידִי כַנַּחַל דִּמְעָה יוֹמָם וָלַיְלָה, אַל תִּתְּנִי פוּגַת לָךְ, אַל תִּדֹּם בַּת עֵינֵךְ: קוּמִי רֹנִּי בַלַּיְלָה לְרֹאשׁ אַשְׁמֻרוֹת, שִׁפְכִי כַמַּיִם לִבֵּךְ נֹכַח פְּנֵי אֲדֹנָי, שְׂאִי אֵלָיו כַּפַּיִךְ עַל נֶפֶשׁ עוֹלָלַיִךְ הָעֲטוּפִים בְּרָעָב בְּרֹאשׁ כָּל חוּצוֹת: רְאֵה יהוה וְהַבִּיטָה לְמִי עוֹלַלְתָּ כֹּה, אִם תֹּאכַלְנָה נָשִׁים פִּרְיָם עֹלְלֵי טִפֻּחִים, אִם יֵהָרֵג בְּמִקְדַּשׁ אֲדֹנָי כֹּהֵן וְנָבִיא: שָׁכְבוּ לָאָרֶץ חוּצוֹת נַעַר וְזָקֵן, בְּתוּלֹתַי וּבַחוּרַי נָפְלוּ בֶחָרֶב, הָרַגְתָּ בְּיוֹם אַפֶּךָ, טָבַחְתָּ לֹא חָמָלְתָּ: תִּקְרָא כְיוֹם מוֹעֵד מְגוּרַי מִסָּבִיב וְלֹא הָיָה בְּיוֹם אַף יהוה פָּלִיט וְשָׂרִיד, אֲשֶׁר טִפַּחְתִּי וְרִבִּיתִי אֹיְבִי כִלָּם:","cond":["tishaaBeav"]},{"kind":"instruction","text":"פרק ג'","cond":["tishaaBeav"]},{"kind":"text","text":"אֲנִי הַגֶּבֶר רָאָה עֳנִי בְּשֵׁבֶט עֶבְרָתוֹ: אוֹתִי נָהַג וַיֹּלַךְ חֹשֶׁךְ וְלֹא אוֹר: אַךְ בִּי יָשֻׁב יַהֲפֹךְ יָדוֹ כָּל הַיּוֹם: בִּלָּה בְשָׂרִי וְעוֹרִי, שִׁבַּר עַצְמוֹתָי: בָּנָה עָלַי, וַיַּקַּף רֹאשׁ וּתְלָאָה: בְּמַחֲשַׁכִּים הוֹשִׁיבַנִי כְּמֵתֵי עוֹלָם: גָּדַר בַּעֲדִי וְלֹא אֵצֵא, הִכְבִּיד נְחָשְׁתִּי: גַּם כִּי אֶזְעַק וַאֲשַׁוֵּעַ שָׂתַם תְּפִלָּתִי: גָּדַר דְּרָכַי בְּגָזִית, נְתִיבֹתַי עִוָּה: דֹּב אֹרֵב הוּא לִי, אֲרִי בְּמִסְתָּרִים: דְּרָכַי סוֹרֵר וַיְפַשְּׁחֵנִי, שָׂמַנִי שֹׁמֵם: דָּרַךְ קַשְׁתּוֹ וַיַּצִּיבֵנִי כַּמַּטָּרָא לַחֵץ: הֵבִיא בְּכִלְיוֹתָי בְּנֵי אַשְׁפָּתוֹ: הָיִיתִי שְּׂחֹק לְכָל עַמִּי, נְגִינָתָם כָּל הַיּוֹם: הִשְׂבִּיעַנִי בַמְּרוֹרִים הִרְוַנִי לַעֲנָה: וַיַּגְרֵס בֶּחָצָץ שִׁנָּי, הִכְפִּישַׁנִי בָּאֵפֶר: וַתִּזְנַח מִשָּׁלוֹם נַפְשִׁי, נָשִׁיתִי טוֹבָה: וָאֹמַר אָבַד נִצְחִי וְתוֹחַלְתִּי מֵיהוה: זְכָר עָנְיִי וּמְרוּדִי, לַעֲנָה וָרֹאשׁ: זָכוֹר תִּזְכּוֹר וְתָשׁוֹחַ עָלַי נַפְשִׁי: זֹאת אָשִׁיב אֶל לִבִּי, עַל כֵּן אוֹחִיל: חַסְדֵי יהוה כִּי לֹא תָמְנוּ, כִּי לֹא כָלוּ רַחֲמָיו: חֲדָשִׁים לַבְּקָרִים רַבָּה אֱמוּנָתֶךָ: חֶלְקִי יהוה אָמְרָה נַפְשִׁי, עַל כֵּן אוֹחִיל לוֹ: טוֹב יהוה לְקֹוָו, לְנֶפֶשׁ תִּדְרְשֶׁנּוּ: טוֹב וְיָחִיל וְדוּמָם לִתְשׁוּעַת יהוה: טוֹב לַגֶּבֶר כִּי יִשָּׂא עֹל בִּנְעוּרָיו: יֵשֵׁב בָּדָד וְיִדֹּם כִּי נָטַל עָלָיו: יִתֵּן בֶּעָפָר פִּיהוּ, אוּלַי יֵשׁ תִּקְוָה: יִתֵּן לְמַכֵּהוּ לֶחִי, יִשְׂבַּע בְּחֶרְפָּה: כִּי לֹא יִזְנַח לְעוֹלָם אֲדֹנָי: כִּי אִם הוֹגָה וְרִחַם כְּרֹב חֲסָדָיו: כִּי לֹא עִנָּה מִלִּבּוֹ, וַיַּגֶּה בְּנֵי אִישׁ: לְדַכֵּא תַּחַת רַגְלָיו כֹּל אֲסִירֵי אָרֶץ: לְהַטּוֹת מִשְׁפַּט גָּבֶר נֶגֶד פְּנֵי עֶלְיוֹן: לְעַוֵּת אָדָם בְּרִיבוֹ אֲדֹנָי לֹא רָאָה: מִי זֶה אָמַר וַתֶּהִי, אֲדֹנָי לֹא צִוָּה: מִפִּי עֶלְיוֹן לֹא תֵצֵא הָרָעוֹת וְהַטּוֹב: מַה יִּתְאוֹנֵן אָדָם חָי, גֶּבֶר עַל חֲטָאָיו: נַחְפְּשָׂה דְרָכֵינוּ וְנַחְקֹרָה, וְנָשׁוּבָה עַד יהוה: נִשָּׂא לְבָבֵנוּ אֶל כַּפָּיִם, אֶל אֵל בַּשָּׁמָיִם: נַחְנוּ פָשַׁעְנוּ וּמָרִינוּ, אַתָּה לֹא סָלָחְתָּ: סַכֹּתָה בָאַף וַתִּרְדְּפֵנוּ, הָרַגְתָּ לֹא חָמָלְתָּ: סַכּוֹתָה בֶעָנָן לָךְ מֵעֲבוֹר תְּפִלָּה: סְחִי וּמָאוֹס תְּשִׂימֵנוּ בְּקֶרֶב הָעַמִּים: פָּצוּ עָלֵינוּ פִּיהֶם כָּל אֹיְבֵינוּ: פַּחַד וָפַחַת הָיָה לָנוּ, הַשֵּׁאת וְהַשָּׁבֶר: פַּלְגֵי מַיִם תֵּרַד עֵינִי עַל שֶׁבֶר בַּת עַמִּי: עֵינִי נִגְּרָה וְלֹא תִדְמֶה מֵאֵין הֲפֻגוֹת: עַד יַשְׁקִיף וְיֵרֶא יהוה מִשָּׁמָיִם: עֵינִי עוֹלְלָה לְנַפְשִׁי מִכֹּל בְּנוֹת עִירִי: צוֹד צָדוּנִי כַּצִּפּוֹר אֹיְבַי חִנָּם: צָמְתוּ בַבּוֹר חַיָּי וַיַּדּוּ אֶבֶן בִּי: צָפוּ מַיִם עַל רֹאשִׁי, אָמַרְתִּי נִגְזָרְתִּי: קָרָאתִי שִׁמְךָ יהוה מִבּוֹר תַּחְתִּיּוֹת: קוֹלִי שָׁמָעְתָּ, אַל תַּעְלֵם אָזְנְךָ לְרַוְחָתִי לְשַׁוְעָתִי: קָרַבְתָּ בְּיוֹם אֶקְרָאֶךָּ, אָמַרְתָּ אַל תִּירָא: רַבְתָּ אֲדֹנָי רִיבֵי נַפְשִׁי, גָּאַלְתָּ חַיָּי: רָאִיתָה יהוה עַוָּתָתִי, שָׁפְטָה מִשְׁפָּטִי: רָאִיתָה כָּל נִקְמָתָם, כָּל מַחְשְׁבֹתָם לִי: שָׁמַעְתָּ חֶרְפָּתָם יהוה, כָּל מַחְשְׁבֹתָם עָלָי: שִׂפְתֵי קָמַי וְהֶגְיוֹנָם עָלַי כָּל הַיּוֹם: שִׁבְתָּם וְקִימָתָם הַבִּיטָה, אֲנִי מַנְגִּינָתָם: תָּשִׁיב לָהֶם גְּמוּל, יהוה, כְּמַעֲשֵׂה יְדֵיהֶם: תִּתֵּן לָהֶם מְגִנַּת לֵב, תַּאֲלָתְךָ לָהֶם: תִּרְדֹּף בְּאַף וְתַשְׁמִידֵם מִתַּחַת שְׁמֵי יהוה:","cond":["tishaaBeav"]},{"kind":"instruction","text":"פרק ד'","cond":["tishaaBeav"]},{"kind":"text","text":"אֵיכָה יוּעַם זָהָב יִשְׁנֶא הַכֶּתֶם הַטּוֹב, תִּשְׁתַּפֵּכְנָה אַבְנֵי קֹדֶשׁ בְּרֹאשׁ כָּל חוּצוֹת: בְּנֵי צִיּוֹן הַיְקָרִים הַמְסֻלָּאִים בַּפָּז, אֵיכָה נֶחְשְׁבוּ לְנִבְלֵי חֶרֶשׂ מַעֲשֵׂה יְדֵי יוֹצֵר: גַּם תַּנִּים חָלְצוּ שַׁד, הֵינִיקוּ גּוּרֵיהֶן, בַּת עַמִּי לְאַכְזָר כַּיְעֵנִים בַּמִּדְבָּר: דָּבַק לְשׁוֹן יוֹנֵק אֶל חִכּוֹ בַּצָּמָא, עוֹלָלִים שָׁאֲלוּ לֶחֶם, פֹּרֵשׂ אֵין לָהֶם: הָאֹכְלִים לְמַעֲדַנִּים נָשַׁמּוּ בַּחוּצוֹת, הָאֱמֻנִים עֲלֵי תוֹלָע חִבְּקוּ אַשְׁפַּתּוֹת: וַיִּגְדַּל עֲוׂן בַּת עַמִּי מֵחַטַּאת סְדֹם הַהֲפוּכָה כְמוֹ רָגַע, וְלֹא חָלוּ בָהּ יָדָיִם: זַכּוּ נְזִירֶיהָ מִשֶּׁלֶג, צַחוּ מֵחָלָב, אָדְמוּ עֶצֶם מִפְּנִינִים, סַפִּיר גִּזְרָתָם: חָשַׁךְ מִשְּׁחוֹר תָּאֳרָם, לֹא נִכְּרוּ בַּחוּצוֹת, צָפַד עוֹרָם עַל עַצְמָם, יָבֵשׁ הָיָה כָעֵץ: טוֹבִים הָיוּ חַלְלֵי חֶרֶב מֵחַלְלֵי רָעָב, שֶׁהֵם יָזוּבוּ מְדֻקָּרִים מִתְּנוּבֹת שָׂדָי: יְדֵי נָשִׁים רַחֲמָנִיּוֹת בִּשְּׁלוּ יַלְדֵיהֶן, הָיוּ לְבָרוֹת לָמוֹ בְּשֶׁבֶר בַּת עַמִּי: כִּלָּה יהוה אֶת חֲמָתוֹ, שָׁפַךְ חֲרוֹן אַפּוֹ, וַיַּצֶּת אֵשׁ בְּצִיּוֹן וַתֹּאכַל יְסוֹדֹתֶיהָ: לֹא הֶאֱמִינוּ מַלְכֵי אֶרֶץ כֹּל יֹשְׁבֵי תֵבֵל, כִּי יָבֹא צַר וְאוֹיֵב בְּשַׁעֲרֵי יְרוּשָׁלָיִם: מֵחַטֹּאת נְבִיאֶיהָ, עֲוׂנוֹת כֹּהֲנֶיהָ, הַשֹּׁפְכִים בְּקִרְבָּהּ דַּם צַדִּיקִים: נָעוּ עִוְרִים בַּחוּצוֹת נְגֹאֲלוּ בַּדָּם, בְּלֹא יוּכְלוּ יִגְּעוּ בִּלְבֻשֵׁיהֶם: סוּרוּ טָמֵא, קָרְאוּ לָמוֹ, סוּרוּ סוּרוּ אַל תִּגָּעוּ, כִּי נָצוּ גַּם נָעוּ, אָמְרוּ בַּגּוֹיִם לֹא יוֹסִיפוּ לָגוּר: פְּנֵי יהוה חִלְּקָם לֹא יוֹסִיף לְהַבִּיטָם, פְּנֵי כֹהֲנִים לֹא נָשָׂאוּ וּזְקֵנִים לֹא חָנָנוּ: עוֹדֵינוּ תִּכְלֶינָה עֵינֵינוּ אֶל עֶזְרָתֵנוּ הָבֶל, בְּצִפִּיָּתֵנוּ צִפִּינוּ אֶל גּוֹי לֹא יוֹשִׁעַ: צָדוּ צְעָדֵינוּ מִלֶּכֶת בִּרְחֹבֹתֵינוּ, קָרַב קִצֵּינוּ מָלְאוּ יָמֵינוּ כִּי בָא קִצֵּינוּ: קַלִּים הָיוּ רֹדְפֵינוּ מִנִּשְׁרֵי שָׁמָיִם, עַל הֶהָרִים דְּלָקֻנוּ, בַּמִּדְבָּר אָרְבוּ לָנוּ: רוּחַ אַפֵּינוּ מְשִׁיחַ יהוה נִלְכַּד בִּשְׁחִיתוֹתָם, אֲשֶׁר אָמַרְנוּ בְּצִלּוֹ נִחְיֶה בַגּוֹיִם: שִׂישִׂי וְשִׂמְחִי בַּת אֱדוֹם יוֹשֶׁבֶת בְּאֶרֶץ עוּץ, גַּם עָלַיִךְ תַּעֲבָר כּוֹס, תִּשְׁכְּרִי וְתִתְעָרִי: תַּם עֲוׂנֵךְ בַּת צִיּוֹן, לֹא יוֹסִיף לְהַגְלוֹתֵךְ, פָּקַד עֲוׂנֵךְ בַּת אֱדוֹם, גִּלָּה עַל חַטֹּאתָיִךְ:","cond":["tishaaBeav"]},{"kind":"instruction","text":"פרק ה'","cond":["tishaaBeav"]},{"kind":"text","text":"זְכֹר יהוה מֶה הָיָה לָנוּ, הַבִּיטָה וּרְאֵה אֶת חֶרְפָּתֵנוּ: נַחֲלָתֵנוּ נֶהֶפְכָה לְזָרִים, בָּתֵּינוּ לְנָכְרִים: יְתוֹמִים הָיִינוּ וְאֵין אָב, אִמֹּתֵינוּ כְּאַלְמָנוֹת: מֵימֵינוּ בְּכֶסֶף שָׁתִינוּ, עֵצֵינוּ בִּמְחִיר יָבֹאוּ: עַל צַוָּארֵנוּ נִרְדָּפְנוּ, יָגַעְנוּ וְלֹא הוּנַח לָנוּ: מִצְרַיִם נָתַנּוּ יָד, אַשּׁוּר לִשְׂבֹּעַ לָחֶם: אֲבֹתֵינוּ חָטְאוּ וְאֵינָם, וַאֲנַחְנוּ עֲוׂנֹתֵיהֶם סָבָלְנוּ: עֲבָדִים מָשְׁלוּ בָנוּ, פֹּרֵק אֵין מִיָּדָם: בְּנַפְשֵׁנוּ נָבִיא לַחְמֵנוּ מִפְּנֵי חֶרֶב הַמִּדְבָּר: עוֹרֵנוּ כְּתַנּוּר נִכְמָרוּ מִפְּנֵי זַלְעֲפוֹת רָעָב: נָשִׁים בְּצִיּוֹן עִנּוּ, בְּתֻלֹת בְּעָרֵי יְהוּדָה: שָׂרִים בְּיָדָם נִתְלוּ, פְּנֵי זְקֵנִים לֹא נֶהְדָּרוּ: בַּחוּרִים טְחוֹן נָשָׂאוּ, וּנְעָרִים בָּעֵץ כָּשָׁלוּ: זְקֵנִים מִשַּׁעַר שָׁבָתוּ, בַּחוּרִים מִנְּגִינָתָם: שָׁבַת מְשׂוֹשׂ לִבֵּנוּ, נֶהְפַּךְ לְאֵבֶל מְחֹלֵנוּ: נָפְלָה עֲטֶרֶת רֹאשֵׁנוּ, אוֹי נָא לָנוּ כִּי חָטָאנוּ: עַל זֶה הָיָה דָוֶה לִבֵּנוּ, עַל אֵלֶּה חָשְׁכוּ עֵינֵינוּ: עַל הַר צִיּוֹן שֶׁשָּׁמֵם, שׁוּעָלִים הִלְּכוּ בוֹ: אַתָּה יהוה לְעוֹלָם תֵּשֵׁב, כִּסְאֲךָ לְדֹר וָדוֹר: לָמָּה לָנֶצַח תִּשְׁכָּחֵנוּ, תַּעַזְבֵנוּ לְאֹרֶךְ יָמִים: הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם: כִּי אִם מָאֹס מְאַסְתָּנוּ, קָצַפְתָּ עָלֵינוּ עַד מְאֹד:","cond":["tishaaBeav"]},{"kind":"special","text":"הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם:","cond":["tishaaBeav"]},{"kind":"header","text":"קינות לליל תשעה באב","cond":["tishaaBeav"]},{"kind":"instruction","text":"קינות לליל תשעה באב\n\nקינה א'","cond":["tishaaBeav"]},{"kind":"text","text":"זְכֹר יהוה מֶה-הָיָה לָנוּ אוֹי. הַבִּיטָה וּרְאֵה אֶת-חֶרְפָּתֵנוּ: אוֹי מֶה הָיָה לָנוּ.\nנַחֲלָתֵנוּ נֶהֶפְכָה לְזָרִים אוֹי. בָּתֵּינוּ לְנָכְרִים: אוֹי מֶה הָיָה לָנוּ.\nיְתוֹמִים הָיִינוּ וְאֵין אָב אוֹי. אִמּוֹתֵינוּ מְקוֹנְנוֹת בְּחֹדֶשׁ אָב. אוֹי מֶה הָיָה לָנוּ.\nמֵימֵינוּ בְּכֶסֶף שָׁתִינוּ אוֹי. כִּי נִסּוּךְ הַמַּיִם בָּזִינוּ. אוֹי מֶה הָיָה לָנוּ.\nעַל צַוָּארֵנוּ נִרְדָּפְנוּ אוֹי. כִּי שִׂנְאַת חִנָּם רָדָפְנוּ. אוֹי מֶה הָיָה לָנוּ.\nמִצְרַיִם נָתַנּוּ יָד אוֹי. וְאַשּׁוּר צָדוּנוּ כְּצַיָּד. אוֹי מֶה הָיָה לָנוּ.\nאֲבֹתֵינוּ חָטְאוּ וְאֵינָם אוֹי. וַאֲנַחְנוּ סוֹבְלִים אֶת עֲוׂנָם. אוֹי מֶה הָיָה לָנוּ.\nעֲבָדִים מָשְׁלוּ בָנוּ אוֹי. כִּי שִׁלּוּחַ עֲבָדִים בִּטַּלְנוּ. אוֹי מֶה הָיָה לָנוּ.\nבְּנַפְשֵׁנוּ נָבִיא לַחְמֵנוּ אוֹי. כִּי קָפַצְנוּ מֵעָנִי יָדֵנוּ. אוֹי מֶה הָיָה לָנוּ.\nעוֹרֵנוּ כְּתַנּוּר נִכְמָרוּ אוֹי. כִּי כְבוֹדָם בְּקָלוֹן הֵמִירוּ. אוֹי מֶה הָיָה לָנוּ.\nנָשִׁים בְּצִיּוֹן עִנּוּ אוֹי. כִּי אִישׁ אֶת אֵשֶׁת רֵעֵהוּ טִמְּאוּ וְזִנּוּ. אוֹי מֶה הָיָה לָנוּ.\nשָׂרִים בְּיָדָם נִתְלוּ אוֹי. כִּי גְּזֵלַת הֶעָנִי חָמְסוּ וְגָזְלוּ. אוֹי מֶה הָיָה לָנוּ.\nבַּחוּרִים טְחוֹן נָשָׂאוּ אוֹי. כִּי בְּבֵית זוֹנָה נִמְצָאוּ. אוֹי מֶה הָיָה לָנוּ.\nזְקֵנִים מִשַּׁעַר שָׁבָתוּ אוֹי. כִּי מִשְׁפַּט יָתוֹם וְאַלְמָנָה עִוְּתוּ. אוֹי מֶה הָיָה לָנוּ.\nשָׁבַת מְשׂוֹשׂ לִבֵּנוּ אוֹי. כִּי נִבְטְלוּ עוֹלֵי רְגָלֵינוּ. אוֹי מֶה הָיָה לָנוּ.\nנָפְלָה עֲטֶרֶת רֹאשֵׁנוּ אוֹי. כִּי נִשְׂרַף בֵּית מִקְדָּשֵׁנוּ. אוֹי מֶה הָיָה לָנוּ.\nעַל זֶה הָיָה דָוֶה לִבֵּנוּ אוֹי. כִּי נֻטַּל כְּבוֹד בֵּית מַאֲוָיֵנוּ. אוֹי מֶה הָיָה לָנוּ.\nעַל הַר צִיּוֹן שֶׁשָּׁמֵם אוֹי. כִּי נִתַּן עָלָיו שִׁקּוּץ מְשׁוֹמֵם. אוֹי מֶה הָיָה לָנוּ.\nאַתָּה יהוה לְעוֹלָם תֵּשֵׁב, כִּסְאֲךָ לְדוֹר וָדוֹר: לָמָּה לָנֶצַח תִּשְׁכָּחֵנוּ, תַּעַזְבֵנוּ לְאֹרֶךְ יָמִים: הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם: כִּי אִם מָאֹס מְאַסְתָּנוּ, קָצַפְתָּ עָלֵינוּ עַד מְאֹד:\nהֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה חַדֵּשׁ יָמֵינוּ כְּקֶדֶם:","cond":["tishaaBeav"]},{"kind":"instruction","text":"קינה ב'\nקינה לליל תשעה באב שחל במוצאי שבת:","cond":["tishaaBeav","sun"]},{"kind":"text","text":"אֵיךְ מִפִּי בֵּן וּבַת, הֲגוֹת קִינִים רַבַּת, תְּמוּר שִׁירִים וְחֶדְוַת.\nוִיהִי נֹעַם נִשְׁבַּת בְּמוֹצָאֵי שַׁבָּת.\n\nאוֹי כִּי נִגְזְרָה גְּזֵרָה, בָּחֳרִי אַף וְגַם עֶבְרָה, וְאַפּוֹ בָּנוּ חָרָה, וּבָעֲרָה חֲמָתוֹ כְּלַבַּת.\nוִיהִי נֹעַם נִשְׁבַּת בְּמוֹצָאֵי שַׁבָּת.\n\nאוֹי כִּי בָתֵּינוּ שִׁנּוּ, וּבְתוּלוֹתֵינוּ עִנּוּ, וּפָנֵינוּ נִשְׁתַּנּוּ, וְגַם הֻשְׁחֲרוּ כְּמַחֲבַת.\nוִיהִי נֹעַם נִשְׁבַּת בְּמוֹצָאֵי שַׁבָּת.\n\nאוֹי כִּי שַׁדּוּנוּ, וְגַם הִפִּילוּ בָנוּ פְּגָרִים, בְּנֵי צִיּוֹן הַיְקָרִים, הָיוּ נְצוּרִים כְּבָבַת.\nוִיהִי נֹעַם נִשְׁבַּת בְּמוֹצָאֵי שַׁבָּת.\n\nאוֹי כִּי נָפְלָה עֲטֶרֶת, וְגָבְרָה כָּתֵף סוֹרֶרֶת, וְחָדַל הוֹד תִּפְאֶרֶת, צִמְצוּם שֶׁכֶן חִבַּת.\nוִיהִי נֹעַם נִשְׁבַּת בְּמוֹצָאֵי שַׁבָּת.\n\nאוֹי כִּי נֻטְּלָה מְנוֹרָה, וּקְטֹרֶת לְבֹנָה הַטְּהוֹרָה, וְנִבְזָה גָּזִית מְיֻקָּרָה, אָכְלָה אֶרֶץ זָבַת.\nוִיהִי נֹעַם נִשְׁבַּת בְּמוֹצָאֵי שַׁבָּת.","cond":["tishaaBeav","sun"]},{"kind":"instruction","text":"קינה ג'","cond":["tishaaBeav"]},{"kind":"text","text":"בְּלֵיל זֶה יִבְכָּיוּן וְיֵילִילוּ בָּנַי, בְּלֵיל זֶה חָרַב בֵּית קָדְשִׁי וְנִשְׂרְפוּ אַרְמוֹנַי. וְכָל בֵּית יִשְׂרָאֵל יֶהְגּוּ בִיגוֹנַי. וְיִבְכּוּ אֶת הַשְּׂרֵפָה אֲשֶׁר שָׂרַף יהוה:\n\nבְּלֵיל זֶה תְּיַלֵּל מַר עֲנִיָּה נֶחְדֶּלֶת, וּמִבֵּית אָבִיהָ בַּחַיִּים מֻבְדֶּלֶת. וְיָצְאָה מִבֵּיתוֹ וְנִסְגַּר הַדֶּלֶת, וְהָלְכָה בַּשִּׁבְיָה בְּכָל פֶּה נֶאֱכֶלֶת. בְּיוֹם שֻׁלְּחָה בְּאֵשׁ בּוֹעֶרֶת וְאוֹכֶלֶת, וְאֵשׁ עִם גַּחֶלֶת יָצְאָה מֵאֵת יהוה.\nבְּלֵיל זֶה יִבְכָּיוּן וְיֵילִילוּ בָּנַי, בְּלֵיל זֶה חָרַב בֵּית קָדְשִׁי וְנִשְׂרְפוּ אַרְמוֹנַי.\n\nבְּלֵיל זֶה הַגַּלְגַּל סִבֵּב הַחוֹבָה, רִאשׁוֹן גַּם שֵׁנִי בֵּיתִי נֶחְרְבָה. וְעוֹד לֹא רֻחָמָה בַּת הַשּׁוֹבָבָה, הֻשְׁקְתָה מֵי רוֹשׁ וְאֶת בִּטְנָהּ צָבָה. וְשֻׁלְּחָה מִבֵּיתוֹ וְגַם נָשְׁתָה טוֹבָה, גְּדוֹלָה הַשִּׂנְאָה מֵאֵת אֲשֶׁר אֲהֵבָהּ, וּכְאַלְמְנוּת חַיּוּת כְּאִשָּׁה נֶעֱזָבָה. וַתֹּאמֶר צִיּוֹן עֲזָבַנִי יהוה.\nבְּלֵיל זֶה יִבְכָּיוּן וְיֵילִילוּ בָּנַי, בְּלֵיל זֶה חָרַב בֵּית קָדְשִׁי וְנִשְׂרְפוּ אַרְמוֹנַי.\n\nבְּלֵיל זֶה קָדַרְתִּי וְחָשְׁכוּ הַמְּאוֹרוֹת, לְחֻרְבַּן בֵּית קָדְשִׁי וּבִטּוּל מִשְׁמָרוֹת. בְּלֵיל זֶה סַבּוּנִי אֲפָפוּנִי צָרוֹת, וְגַם קָרָא מוֹעֵד בְּדִין חָמֵשׁ גְּזֵרוֹת. בְּכִי חִנָּם בָּכוּ וְנִקְבַּע לְדוֹרוֹת, יַעַן כִּי הָיְתָה סִבָּה מֵאֵת יהוה.\nבְּלֵיל זֶה יִבְכָּיוּן וְיֵילִילוּ בָּנַי, בְּלֵיל זֶה חָרַב בֵּית קָדְשִׁי וְנִשְׂרְפוּ אַרְמוֹנַי.\n\nבְּלֵיל זֶה אֵרְעוּ בוֹ חָמֵשׁ מְאוֹרָעוֹת, גָּזַר עַל אָבוֹת בִּפְרֹעַ פְּרָעוֹת. וְדָבְקוּ בוֹ צָרוֹת מְצֵרוֹת וְגַם רָעוֹת, יוֹם מוּכָן הָיָה בִּפְגֹּעַ פְּגָעוֹת. וְהֶעֱמִיד הָאוֹיֵב וְהֵרִים קוֹל זְוָעוֹת, קוּם כִּי זֶה הַיּוֹם אֲשֶׁר אָמַר יהוה.\nבְּלֵיל זֶה יִבְכָּיוּן וְיֵילִילוּ בָּנַי, בְּלֵיל זֶה חָרַב בֵּית קָדְשִׁי וְנִשְׂרְפוּ אַרְמוֹנַי.","cond":["tishaaBeav"]},{"kind":"instruction","text":"קינה ד'","cond":["tishaaBeav"]},{"kind":"text","text":"שֹׁמְרוֹן קוֹל תִּתֵּן: מְצָאוּנִי עֲוׂנַי, לְאֶרֶץ אַחֶרֶת יְצָאוּנִי בָנַי.\nוְאָהֳלִיבָה תִּזְעַק: נִשְׂרְפוּ אַרְמוֹנַי.\nוַתֹּאמֶר צִיּוֹן: עֲזָבַנִי יהוה.\n\nלֹא לָךְ, אָהֳלִיבָה, חֲשֹׁב עָנְיֵךְ כְּעָנְיִי, הֲתַמְשִׁילִי חָלְיֵךְ לְשִׁבְרִי וּלְחָלְיִי? אֲנִי אָהֳלָה סוּרָה בָּגַדְתִּי בְקָשְׁיִי, וְקָם עָלַי כַּחֲשִׁי וְעָנָה בִי מֶרְיִי, וּלְמִקְצָת הַיָּמִים שִׁלַּמְתִּי נִשְׁיִי, וְתִגְלַת פִּלְאֶסֶר אָכַל אֶת פִּרְיִי, חֶמְדָּתִי פָּשַׁט וְהִצִּיל אֶת עֶדְיִי, וְלַחֲלַח וְחָבוֹר נָשָׂא אֶת שִׁבְיִי. דֹּמִי, אָהֳלִיבָה, וְאַל תִּבְכִּי כְּבִכְיִי, שְׁנָתַיִךְ אָרְכוּ, וְלֹא אָרְכוּ שָׁנַי.\n\nוְאָהֳלִיבָה תִּזְעַק: נִשְׂרְפוּ אַרְמוֹנַי.\nוַתֹּאמֶר צִיּוֹן: עֲזָבַנִי יהוה.\n\nמְשִׁיבָה אָהֳלִיבָה: אֲנִי כֵן נֶעֱקַשְׁתִּי, וּבְאַלּוּף נְעוּרַי כְּאָהֳלָה בָּגַדְתִּי. דֹּמִי, אַהֳלָה, כִּי יְגוֹנִי זָכַרְתִּי. נָדַדְתְּ אַתְּ אַחַת, וְרַבּוֹת נָדַדְתִּי. הִנֵּה, בְּיַד הַכַּשְׂדִּים פַּעֲמַיִם נִלְכַּדְתִּי, וּשְׁבִיָּה עֲנִיָּה לְבָבֶל יָרַדְתִּי, וְנִשְׂרַף הַהֵיכָל אֲשֶׁר בּוֹ נִכְבַּדְתִּי, וּלְשִׁבְעִים שָׁנָה בְּבָבֶל נִפְקַדְתִּי, וְשַׁבְתִּי לְצִיּוֹן עוֹד וְהֵיכָל יָסַדְתִּי, גַּם זֹאת הַפַּעַם מְעַט לֹא עָמַדְתִּי, עַד לְקָחַנִי אֱדוֹם וְכִמְעַט אָבַדְתִּי, וְעַל כָּל הָאֲרָצוֹת נָפְצוּ הֲמוֹנַי.\n\nוְאָהֳלִיבָה תִּזְעַק: נִשְׂרְפוּ אַרְמוֹנַי.\nוַתֹּאמֶר צִיּוֹן: עֲזָבַנִי יהוה.\n\nהַחוֹמֵל עַל דַּל, חֲמֹל עַל דַּלּוּתָם, וּרְאֵה שׁוֹמְמוּתָם וְאֹרֶךְ גָּלוּתָם. אַל תִּקְצֹף עַד מְאֹד, וּרְאֵה שִׁפְלוּתָם, וְאַל לָעַד תִּזְכֹּר עֲוֹנָם וְסִכְלוּתָם. רְפָא נָא אֶת שִׁבְרָם, וְנַחֵם אֲבֵלוּתָם, כִּי אַתָּה שִׂבְרָם וְאַתָּה אֱיָלוּתָם.\nחַדֵּשׁ יָמֵינוּ כִּימֵי קַדְמוֹנַי, כְּנָאֳמֶךָ: \"בּוֹנֵה יְרוּשָׁלַיִם יהוה\".","cond":["tishaaBeav"]},{"kind":"instruction","text":"קינה ה'","cond":["tishaaBeav"]},{"kind":"text","text":"עַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nאָז בַּחֲטָאֵינוּ חָרַב מִקְדָּשׁ וּבַעֲוׂנוֹתֵינוּ נִשְׂרַף הֵיכָל. בְּאֶרֶץ חֻבְּרָה לָהּ קָשְׁרָה מִסְפֵּד, וּצְבָא הַשָּׁמַיִם נָשְׂאוּ קִינָה.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nגַּם בָּכוּ בְּמֶרֶר שִׁבְטֵי יַעֲקֹב, וְאַף מַזָּלוֹת יִזְּלוּ דִּמְעָה. דִּגְלֵי יְשֻׁרוּן חָפוּ רֹאשָׁם, וְכִימָה וּכְסִיל קָדְרוּ פְּנֵיהֶם.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nהֶעְתִּירוּ אָבוֹת וְלֹא שָׁמַע אֵל, צָעֲקוּ בָנִים וְלֹא עָנָה אָב. וְקוֹל הַתֹּר נִשְׁמַע בַּמָּרוֹם, וְרוֹעֶה נֶאֱמָן לֹא הִטָּה אֹזֶן.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nזֶרַע קֹדֶשׁ לָבְשׁוּ שַׂקִּים, וּצְבָא הַשָּׁמַיִם גַּם הֵם שַׂק הוּשַׂם כְּסוּתָם. חָשַׁךְ הַשֶּׁמֶשׁ וְיָרֵחַ קָדַר, וְכוֹכָבִים וּמַזָּלוֹת אָסְפוּ נָגְהָם.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nטָלֶה רִאשׁוֹן בָּכָה בְּמַר נֶפֶשׁ, עַל כִּי כְבָשָׂיו לָטֶבַח הוּבָלוּ. יְלָלָה הִשְׁמִיעַ שׁוֹר בַּמְּרוֹמִים, כִּי עַל צַוָּארֵנוּ נִרְדַּפְנוּ כֻּלָּנוּ.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nכּוֹכַב תְּאוֹמִים נִרְאָה חָלוּק, כִּי דַּם אַחִים נִשְׁפַּךְ כַּמַּיִם. לָאָרֶץ בִּקֵּשׁ לִפֹּל סַרְטָן, כִּי נִתְעַלַּפְנוּ מִפְּנֵי צָמָא.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nמָרוֹם נִבְעַת מִפְּנֵי אַרְיֵה, כִּי שַׁאֲגָתֵנוּ לֹא עָלְתָה לַמָּרוֹם. נֶהֶרְגוּ בְתוּלוֹת וְגַם בַּחוּרִים, כִּי עַל כֵּן בְּתוּלָה קָדְרָה פָנֶיהָ.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nסִבֵּב מֹאזְנַיִם וּבִקֵּשׁ תְּחִנָּה, כִּי נִבְחַר לָנוּ מָוֶת מֵחַיִּים. עַקְרָב לָבַשׁ פַּחַד וּרְעָדָה, כִּי בְּחֶרֶב וּבְרָעָב שְׁפָטָנוּ צוּרֵנוּ.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nפַּלְגֵי מַיִם הוֹרִידוּ דִּמְעָה כַּנַּחַל, כִּי אוֹת בַּקֶּשֶׁת לֹא נִתַּן לָנוּ. צָפוּ מַיִם עַל רֹאשֵׁנוּ, וּבִדְלִי מָלֵא חִכֵּנוּ יָבֵשׁ.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nקֵרַבְנוּ קָרְבָּן וְלֹא נִתְקַבֵּל, וּגְדִי פָּסַק שְׂעִיר חַטֹּאתֵינוּ. רַחֲמָנִיּוֹת בִּשְּׁלוּ יַלְדֵּיהֶן, וּמַזַּל דָּגִים הֶעֱלִים עֵינָיו.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nשָׁכַחְנוּ שַׁבָּת בְּלִבּוֹת שׁוֹבָבִים, שַׁדַּי שִׁכַּח כָּל צִדְקוֹתֵינוּ. תְּקַנֵּא לְצִיּוֹן קִנְאָה גְּדוֹלָה, וְתָאִיר לְרַבָּתִי עָם מֵאוֹר נָגְהֶךָ.\n\nתְּרַחֵם צִיּוֹן כַּאֲשֶׁר אָמַרְתָּ, וּתְכוֹנְנֶהָ כַּאֲשֶׁר דִּבַּרְתָּ. תְּמַהֵר יְשׁוּעָה וְתָחִישׁ גְּאֻלָּה וְתָשׁוּב לִירוּשָׁלַיִם בְּרַחֲמִים רַבִּים, כַּכָּתוּב עַל יַד נְבִיאֶךָ: לָכֵן כֹּה אָמַר יהוה: שַׁבְתִּי לִירוּשָׁלַיִם בְּרַחֲמִים, בֵּיתִי יִבָּנֶה בָּהּ נְאֻם יהוה צְבָאוֹת, וְקָו יִנָּטֶה עַל יְרוּשָׁלָיִם: וְנֶאֱמַר עוֹד קְרָא לֵאמֹר: כֹּה אָמַר יהוה צְבָאוֹת: עוֹד תְּפוּצֶנָה עָרַי מִטּוֹב, וְנִחַם יהוה עוֹד אֶת צִיּוֹן וּבָחַר עוֹד בִּירוּשָׁלָיִם: וְנֶאֱמַר: כִּי נִחַם יהוה צִיּוֹן, נִחַם כָּל חָרְבֹתֶיהָ, וַיָּשֶׂם מִדְבָּרָהּ כְּעֵדֶן וְעַרְבָתָהּ כְּגַן יהוה, שָׂשׂוֹן וְשִׂמְחָה יִמָּצֵא בָהּ תּוֹדָה וְקוֹל זִמְרָה:","cond":["tishaaBeav"]},{"kind":"header","text":"מגילת אסתר","cond":["megilatEster"]},{"kind":"instruction","text":"הקורא את המגילה מברך לפניה שלוש ברכות גם בלילה וגם ביום. לדעת השו\"ע מברכים שהחיינו רק בלילה (ואם לא קרא בלילה יברך ביום). בברכת שהחיינו ביום יכוון גם על שאר מצוות היום: מתנות לאביונים, משלוח מנות ומשתה ושמחה. הנוהגים כדעת השו\"ע יכוונו על זה בלילה.","cond":["megilatEster"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ עַל מִקְרָא מְגִלָּה.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁעָשָׂה נִסִּים לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁהֶחֱיָנוּ וְקִיְּמָנוּ וְהִגִּיעָנוּ לַזְּמַן הַזֶּה.","cond":["megilatEster"]},{"kind":"header","text":"פרק א'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק א'","cond":["megilatEster"]},{"kind":"text","text":"וַיְהִי בִּימֵי אֲחַשְׁוֵרוֹשׁ, הוּא אֲחַשְׁוֵרוֹשׁ הַמֹּלֵךְ מֵהֹדּוּ וְעַד כּוּשׁ, שֶׁבַע וְעֶשְׂרִים וּמֵאָה מְדִינָה: בַּיָּמִים הָהֵם, כְּשֶׁבֶת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ עַל כִּסֵּא מַלְכוּתוֹ אֲשֶׁר בְּשׁוּשַׁן הַבִּירָה: בִּשְׁנַת שָׁלוֹשׁ לְמָלְכוֹ עָשָׂה מִשְׁתֶּה לְכָל שָׂרָיו וַעֲבָדָיו, חֵיל פָּרַס וּמָדַי הַפַּרְתְּמִים וְשָׂרֵי הַמְּדִינוֹת לְפָנָיו: בְּהַרְאֹתוֹ אֶת עֹשֶׁר כְּבוֹד מַלְכוּתוֹ וְאֶת יְקָר תִּפְאֶרֶת גְּדוּלָּתוֹ, יָמִים רַבִּים שְׁמוֹנִים וּמְאַת יוֹם: וּבִמְלוֹאת הַיָּמִים הָאֵלֶּה עָשָׂה הַמֶּלֶךְ לְכָל הָעָם הַנִּמְצְאִים בְּשׁוּשַׁן הַבִּירָה לְמִגָּדוֹל וְעַד קָטָן מִשְׁתֶּה שִׁבְעַת יָמִים, בַּחֲצַר גִּנַּת בִּיתַן הַמֶּלֶךְ: חוּר כַּרְפַּס וּתְכֵלֶת אָחוּז בְּחַבְלֵי בוּץ וְאַרְגָּמָן עַל גְּלִילֵי כֶסֶף וְעַמּוּדֵי שֵׁשׁ, מִטּוֹת זָהָב וָכֶסֶף עַל רִצְפַת בַּהַט וָשֵׁשׁ וְדַר וְסֹחָרֶת: וְהַשְׁקוֹת בִּכְלֵי זָהָב וְכֵלִים מִכֵּלִים שׁוֹנִים, וְיֵין מַלְכוּת רָב כְּיַד הַמֶּלֶךְ: וְהַשְּׁתִיָּה כַדָּת אֵין אֹנֵס, כִּי כֵן יִסַּד הַמֶּלֶךְ עַל כָּל רַב בֵּיתוֹ לַעֲשׂוֹת כִּרְצוֹן אִישׁ וָאִישׁ: גַּם וַשְׁתִּי הַמַּלְכָּה עָשְׂתָה מִשְׁתֵּה נָשִׁים, בֵּית הַמַּלְכוּת אֲשֶׁר לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: בַּיּוֹם הַשְּׁבִיעִי כְּטוֹב לֵב הַמֶּלֶךְ בַּיָּיִן, אָמַר לִמְהוּמָן בִּזְּתָא חַרְבוֹנָא בִּגְתָא וַאֲבַגְתָא זֵתַר וְכַרְכַּס שִׁבְעַת הַסָּרִיסִים הַמְשָׁרְתִים אֶת פְּנֵי הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: לְהָבִיא אֶת וַשְׁתִּי הַמַּלְכָּה לִפְנֵי הַמֶּלֶךְ בְּכֶתֶר מַלְכוּת, לְהַרְאוֹת הָעַמִּים וְהַשָּׂרִים אֶת יָפְיָהּ, כִּי טוֹבַת מַרְאֶה הִיא: וַתְּמָאֵן הַמַּלְכָּה וַשְׁתִּי לָבוֹא בִּדְבַר הַמֶּלֶךְ אֲשֶׁר בְּיַד הַסָּרִיסִים, וַיִּקְצֹף הַמֶּלֶךְ מְאֹד וַחֲמָתוֹ בָּעֲרָה בוֹ: וַיֹּאמֶר הַמֶּלֶךְ לַחֲכָמִים יֹדְעֵי הָעִתִּים, כִּי כֵן דְּבַר הַמֶּלֶךְ לִפְנֵי כָּל יֹדְעֵי דָּת וָדִין: וְהַקָּרֹב אֵלָיו כַּרְשְׁנָא שֵׁתָר אַדְמָתָא תַרְשִׁישׁ מֶרֶס מַרְסְנָא מְמוּכָן, שִׁבְעַת שָׂרֵי פָּרַס וּמָדַי רֹאֵי פְּנֵי הַמֶּלֶךְ הַיֹּשְׁבִים רִאשֹׁנָה בַּמַּלְכוּת: כְּדָת מַה לַּעֲשׂוֹת בַּמַּלְכָּה וַשְׁתִּי, עַל אֲשֶׁר לֹא עָשְׂתָה אֶת מַאֲמַר הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ בְּיַד הַסָּרִיסִים: וַיֹּאמֶר מְמוּכָן לִפְנֵי הַמֶּלֶךְ וְהַשָּׂרִים, לֹא עַל הַמֶּלֶךְ לְבַדּוֹ עָוְתָה וַשְׁתִּי הַמַּלְכָּה, כִּי עַל כָּל הַשָּׂרִים וְעַל כָּל הָעַמִּים אֲשֶׁר בְּכָל מְדִינוֹת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: כִּי יֵצֵא דְבַר הַמַּלְכָּה עַל כָּל הַנָּשִׁים לְהַבְזוֹת בַּעְלֵיהֶן בְּעֵינֵיהֶן, בְּאָמְרָם הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ אָמַר לְהָבִיא אֶת וַשְׁתִּי הַמַּלְכָּה לְפָנָיו וְלֹא בָאָה: וְהַיּוֹם הַזֶּה תֹּאמַרְנָה שָׂרוֹת פָּרַס וּמָדַי אֲשֶׁר שָׁמְעוּ אֶת דְּבַר הַמַּלְכָּה לְכֹל שָׂרֵי הַמֶּלֶךְ, וּכְדַי בִּזָּיוֹן וָקָצֶף: אִם עַל הַמֶּלֶךְ טוֹב יֵצֵא דְבַר מַלְכוּת מִלְּפָנָיו וְיִכָּתֵב בְּדָתֵי פָרַס וּמָדַי וְלֹא יַעֲבוֹר, אֲשֶׁר לֹא תָבוֹא וַשְׁתִּי לִפְנֵי הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ וּמַלְכוּתָהּ יִתֵּן הַמֶּלֶךְ לִרְעוּתָהּ הַטּוֹבָה מִמֶּנָּה: וְנִשְׁמַע פִּתְגָם הַמֶּלֶךְ אֲשֶׁר יַעֲשֶׂה בְּכָל מַלְכוּתוֹ כִּי רַבָּה הִיא, וְכָל הַנָּשִׁים יִתְּנוּ יְקָר לְבַעְלֵיהֶן לְמִגָּדוֹל וְעַד קָטָן: וַיִּיטַב הַדָּבָר בְּעֵינֵי הַמֶּלֶךְ וְהַשָּׂרִים, וַיַּעַשׂ הַמֶּלֶךְ כִּדְבַר מְמוּכָן: וַיִּשְׁלַח סְפָרִים אֶל כָּל מְדִינוֹת הַמֶּלֶךְ, אֶל מְדִינָה וּמְדִינָה כִּכְתָבָהּ וְאֶל עַם וָעָם כִּלְשׁוֹנוֹ, לִהְיוֹת כָּל אִישׁ שֹׂרֵר בְּבֵיתוֹ וּמְדַבֵּר כִּלְשׁוֹן עַמּוֹ:","cond":["megilatEster"]},{"kind":"header","text":"פרק ב'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ב'","cond":["megilatEster"]},{"kind":"text","text":"אַחַר הַדְּבָרִים הָאֵלֶּה כְּשֹׁךְ חֲמַת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, זָכַר אֶת וַשְׁתִּי וְאֵת אֲשֶׁר עָשָׂתָה וְאֵת אֲשֶׁר נִגְזַר עָלֶיהָ: וַיֹּאמְרוּ נַעֲרֵי הַמֶּלֶךְ מְשָׁרְתָיו, יְבַקְשׁוּ לַמֶּלֶךְ נְעָרוֹת בְּתוּלוֹת טוֹבוֹת מַרְאֶה: וְיַפְקֵד הַמֶּלֶךְ פְּקִידִים בְּכָל מְדִינוֹת מַלְכוּתוֹ, וְיִקְבְּצוּ אֶת כָּל נַעֲרָה בְתוּלָה טוֹבַת מַרְאֶה אֶל שׁוּשַׁן הַבִּירָה אֶל בֵּית הַנָּשִׁים אֶל יַד הֵגֶא סְרִיס הַמֶּלֶךְ שֹׁמֵר הַנָּשִׁים, וְנָתוֹן תַּמְרוּקֵיהֶן: וְהַנַּעֲרָה אֲשֶׁר תִּיטַב בְּעֵינֵי הַמֶּלֶךְ תִּמְלֹךְ תַּחַת וַשְׁתִּי, וַיִּיטַב הַדָּבָר בְּעֵינֵי הַמֶּלֶךְ וַיַּעַשׂ כֵּן:","cond":["megilatEster"]},{"kind":"special","text":"אִישׁ יְהוּדִי הָיָה בְּשׁוּשַׁן הַבִּירָה, וּשְׁמוֹ מָרְדֳּכַי בֶּן יָאִיר בֶּן שִׁמְעִי בֶּן קִישׁ אִישׁ יְמִינִי:","cond":["megilatEster"]},{"kind":"text","text":"אֲשֶׁר הָגְלָה מִירוּשָׁלַיִם עִם הַגֹּלָה אֲשֶׁר הָגְלְתָה עִם יְכָנְיָה מֶלֶךְ יְהוּדָה, אֲשֶׁר הֶגְלָה נְבוּכַדְנֶאצַּר מֶלֶךְ בָּבֶל: וַיְהִי אֹמֵן אֶת הֲדַסָּה הִיא אֶסְתֵּר בַּת דֹּדוֹ כִּי אֵין לָהּ אָב וָאֵם, וְהַנַּעֲרָה יְפַת תֹּאַר וְטוֹבַת מַרְאֶה וּבְמוֹת אָבִיהָ וְאִמָּהּ לְקָחָהּ מָרְדֳּכַי לוֹ לְבַת: וַיְהִי בְּהִשָּׁמַע דְּבַר הַמֶּלֶךְ וְדָתוֹ, וּבְהִקָּבֵץ נְעָרוֹת רַבּוֹת אֶל שׁוּשַׁן הַבִּירָה אֶל יַד הֵגָי, וַתִּלָּקַח אֶסְתֵּר אֶל בֵּית הַמֶּלֶךְ אֶל יַד הֵגַי שֹׁמֵר הַנָּשִׁים: וַתִּיטַב הַנַּעֲרָה בְעֵינָיו וַתִּשָּׂא חֶסֶד לְפָנָיו, וַיְבַהֵל אֶת תַּמְרוּקֶיהָ וְאֶת מָנוֹתֶהָ לָתֵת לָהּ, וְאֵת שֶׁבַע הַנְּעָרוֹת הָרְאֻיוֹת לָתֶת לָהּ מִבֵּית הַמֶּלֶךְ, וַיְשַׁנֶּהָ וְאֶת נַעֲרוֹתֶיהָ לְטוֹב בֵּית הַנָּשִׁים: לֹא הִגִּידָה אֶסְתֵּר אֶת עַמָּהּ וְאֶת מוֹלַדְתָּהּ, כִּי מָרְדֳּכַי צִוָּה עָלֶיהָ אֲשֶׁר לֹא תַגִּיד: וּבְכָל יוֹם וָיוֹם מָרְדֳּכַי מִתְהַלֵּךְ לִפְנֵי חֲצַר בֵּית הַנָּשִׁים, לָדַעַת אֶת שְׁלוֹם אֶסְתֵּר וּמַה יֵּעָשֶׂה בָּהּ: וּבְהַגִּיעַ תֹּר נַעֲרָה וְנַעֲרָה לָבוֹא אֶל הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, מִקֵּץ הֱיוֹת לָהּ כְּדָת הַנָּשִׁים שְׁנֵים עָשָׂר חֹדֶשׁ כִּי כֵּן יִמְלְאוּ יְמֵי מְרוּקֵיהֶן, שִׁשָּׁה חֳדָשִׁים בְּשֶׁמֶן הַמֹּר וְשִׁשָּׁה חֳדָשִׁים בַּבְּשָׂמִים וּבְתַמְרוּקֵי הַנָּשִׁים: וּבָזֶה הַנַּעֲרָה בָּאָה אֶל הַמֶּלֶךְ, אֵת כָּל אֲשֶׁר תֹּאמַר יִנָּתֵן לָהּ לָבוֹא עִמָּהּ מִבֵּית הַנָּשִׁים עַד בֵּית הַמֶּלֶךְ: בָּעֶרֶב הִיא בָאָה וּבַבֹּקֶר הִיא שָׁבָה אֶל בֵּית הַנָּשִׁים שֵׁנִי, אֶל יַד שַׁעֲשְׁגַז סְרִיס הַמֶּלֶךְ שֹׁמֵר הַפִּילַגְשִׁים, לֹא תָבוֹא עוֹד אֶל הַמֶּלֶךְ כִּי אִם חָפֵץ בָּהּ הַמֶּלֶךְ וְנִקְרְאָה בְשֵׁם: וּבְהַגִּיעַ תֹּר אֶסְתֵּר בַּת אֲבִיחַיִל דֹּד מָרְדֳּכַי אֲשֶׁר לָקַח לוֹ לְבַת לָבוֹא אֶל הַמֶּלֶךְ, לֹא בִקְשָׁה דָּבָר כִּי אִם אֶת אֲשֶׁר יֹאמַר הֵגַי סְרִיס הַמֶּלֶךְ שֹׁמֵר הַנָּשִׁים, וַתְּהִי אֶסְתֵּר נֹשֵׂאת חֵן בְּעֵינֵי כָּל רֹאֶיהָ: וַתִּלָּקַח אֶסְתֵּר אֶל הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ אֶל בֵּית מַלְכוּתוֹ בַּחֹדֶשׁ הָעֲשִׂירִי הוּא חֹדֶשׁ טֵבֵת, בִּשְׁנַת שֶׁבַע לְמַלְכוּתוֹ: וַיֶּאֱהַב הַמֶּלֶךְ אֶת אֶסְתֵּר מִכָּל הַנָּשִׁים וַתִּשָּׂא חֵן וָחֶסֶד לְפָנָיו מִכָּל הַבְּתוּלֹת, וַיָּשֶׂם כֶּתֶר מַלְכוּת בְּרֹאשָׁהּ וַיַּמְלִיכֶהָ תַּחַת וַשְׁתִּי: וַיַּעַשׂ הַמֶּלֶךְ מִשְׁתֶּה גָדוֹל לְכָל שָׂרָיו וַעֲבָדָיו, אֵת מִשְׁתֵּה אֶסְתֵּר, וַהֲנָחָה לַמְּדִינוֹת עָשָׂה וַיִּתֵּן מַשְׂאֵת כְּיַד הַמֶּלֶךְ: וּבְהִקָּבֵץ בְּתוּלוֹת שֵׁנִית, וּמָרְדֳּכַי יֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ: אֵין אֶסְתֵּר מַגֶּדֶת מוֹלַדְתָּהּ וְאֶת עַמָּהּ כַּאֲשֶׁר צִוָּה עָלֶיהָ מָרְדֳּכַי, וְאֶת מַאֲמַר מָרְדֳּכַי אֶסְתֵּר עֹשָׂה כַּאֲשֶׁר הָיְתָה בְאָמְנָה אִתּוֹ: בַּיָּמִים הָהֵם, וּמָרְדֳּכַי יֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ, קָצַף בִּגְתָן וָתֶרֶשׁ שְׁנֵי סָרִיסֵי הַמֶּלֶךְ מִשֹּׁמְרֵי הַסַּף וַיְבַקְשׁוּ לִשְׁלֹחַ יָד בַּמֶּלֶךְ אֲחַשְׁוֵרֹשׁ: וַיִּוָּדַע הַדָּבָר לְמָרְדֳּכַי וַיַּגֵּד לְאֶסְתֵּר הַמַּלְכָּה, וַתֹּאמֶר אֶסְתֵּר לַמֶּלֶךְ בְּשֵׁם מָרְדֳּכַי: וַיְבֻקַּשׁ הַדָּבָר וַיִּמָּצֵא וַיִּתָּלוּ שְׁנֵיהֶם עַל עֵץ, וַיִּכָּתֵב בְּסֵפֶר דִּבְרֵי הַיָּמִים לִפְנֵי הַמֶּלֶךְ:","cond":["megilatEster"]},{"kind":"header","text":"פרק ג'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ג'","cond":["megilatEster"]},{"kind":"text","text":"אַחַר הַדְּבָרִים הָאֵלֶּה גִּדַּל הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ אֶת הָמָן בֶּן הַמְּדָתָא הָאֲגָגִי וַיְנַשְּׂאֵהוּ, וַיָּשֶׂם אֶת כִּסְאוֹ מֵעַל כָּל הַשָּׂרִים אֲשֶׁר אִתּוֹ: וְכָל עַבְדֵי הַמֶּלֶךְ אֲשֶׁר בְּשַׁעַר הַמֶּלֶךְ כֹּרְעִים וּמִשְׁתַּחֲוִים לְהָמָן, כִּי כֵן צִוָּה לוֹ הַמֶּלֶךְ, וּמָרְדֳּכַי לֹא יִכְרַע וְלֹא יִשְׁתַּחֲוֶה: וַיֹּאמְרוּ עַבְדֵי הַמֶּלֶךְ אֲשֶׁר בְּשַׁעַר הַמֶּלֶךְ לְמָרְדֳּכַי, מַדּוּעַ אַתָּה עוֹבֵר אֵת מִצְוַת הַמֶּלֶךְ: וַיְהִי כְּאָמְרָם אֵלָיו יוֹם וָיוֹם וְלֹא שָׁמַע אֲלֵיהֶם, וַיַּגִּידוּ לְהָמָן לִרְאוֹת הֲיַעַמְדוּ דִּבְרֵי מָרְדֳּכַי כִּי הִגִּיד לָהֶם אֲשֶׁר הוּא יְהוּדִי: וַיַּרְא הָמָן כִּי אֵין מָרְדֳּכַי כֹּרֵעַ וּמִשְׁתַּחֲוֶה לוֹ, וַיִּמָּלֵא הָמָן חֵמָה: וַיִּבֶז בְּעֵינָיו לִשְׁלֹח יָד בְּמָרְדֳּכַי לְבַדּוֹ כִּי הִגִּידוּ לוֹ אֶת עַם מָרְדֳּכַי, וַיְבַקֵּשׁ הָמָן לְהַשְׁמִיד אֶת כָּל הַיְּהוּדִים אֲשֶׁר בְּכָל מַלְכוּת אֲחַשְׁוֵרוֹשׁ עַם מָרְדֳּכַי: בַּחֹדֶשׁ הָרִאשׁוֹן הוּא חֹדֶשׁ נִיסָן בִּשְׁנַת שְׁתֵּים עֶשְׂרֵה לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, הִפִּיל פּוּר הוּא הַגּוֹרָל לִפְנֵי הָמָן מִיּוֹם לְיוֹם וּמֵחֹדֶשׁ לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר: וַיֹּאמֶר הָמָן לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ יֶשְׁנוֹ עַם אֶחָד מְפֻזָּר וּמְפֹרָד בֵּין הָעַמִּים בְּכֹל מְדִינוֹת מַלְכוּתֶךָ, וְדָתֵיהֶם שֹׁנוֹת מִכָּל עָם וְאֶת דָּתֵי הַמֶּלֶךְ אֵינָם עֹשִׂים וְלַמֶּלֶךְ אֵין שֹׁוֶה לְהַנִּיחָם: אִם עַל הַמֶּלֶךְ טוֹב יִכָּתֵב לְאַבְּדָם, וַעֲשֶׂרֶת אֲלָפִים כִּכַּר כֶּסֶף אֶשְׁקוֹל עַל יְדֵי עֹשֵׂי הַמְּלָאכָה לְהָבִיא אֶל גִּנְזֵי הַמֶּלֶךְ: וַיָּסַר הַמֶּלֶךְ אֶת טַבַּעְתּוֹ מֵעַל יָדוֹ, וַיִּתְּנָהּ לְהָמָן בֶּן הַמְּדָתָא הָאֲגָגִי צֹרֵר הַיְּהוּדִים: וַיֹּאמֶר הַמֶּלֶךְ לְהָמָן הַכֶּסֶף נָתוּן לָךְ, וְהָעָם לַעֲשׂוֹת בּוֹ כַּטּוֹב בְּעֵינֶיךָ: וַיִּקָּרְאוּ סֹפְרֵי הַמֶּלֶךְ בַּחֹדֶשׁ הָרִאשׁוֹן בִּשְׁלוֹשָׁה עָשָׂר יוֹם בּוֹ, וַיִּכָּתֵב כְּכָל אֲשֶׁר צִוָּה הָמָן אֶל אֲחַשְׁדַּרְפְּנֵי הַמֶּלֶךְ וְאֶל הַפַּחוֹת אֲשֶׁר עַל מְדִינָה וּמְדִינָה וְאֶל שָׂרֵי עַם וָעָם, מְדִינָה וּמְדִינָה כִּכְתָבָהּ וְעַם וָעָם כִּלְשׁוֹנוֹ, בְּשֵׁם הַמֶּלֶךְ אֲחַשְׁוֵרֹשׁ נִכְתָּב וְנֶחְתָּם בְּטַבַּעַת הַמֶּלֶךְ: וְנִשְׁלוֹחַ סְפָרִים בְּיַד הָרָצִים אֶל כָּל מְדִינוֹת הַמֶּלֶךְ, לְהַשְׁמִיד לַהֲרֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלוֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: פַּתְשֶׁגֶן הַכְּתָב לְהִנָּתֵן דָּת בְּכָל מְדִינָה וּמְדִינָה גָּלוּי לְכָל הָעַמִּים, לִהְיוֹת עֲתִדִים לַיּוֹם הַזֶּה: הָרָצִים יָצְאוּ דְחוּפִים בִּדְבַר הַמֶּלֶךְ וְהַדָּת נִתְּנָה בְּשׁוּשַׁן הַבִּירָה, וְהַמֶּלֶךְ וְהָמָן יָשְׁבוּ לִשְׁתּוֹת וְהָעִיר שׁוּשָׁן נָבוֹכָה:","cond":["megilatEster"]},{"kind":"header","text":"פרק ד'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ד'","cond":["megilatEster"]},{"kind":"text","text":"וּמָרְדֳּכַי יָדַע אֶת כָּל אֲשֶׁר נַעֲשָׂה וַיִּקְרַע מָרְדֳּכַי אֶת בְּגָדָיו וַיִּלְבַּשׁ שַׂק וָאֵפֶר, וַיֵּצֵא בְּתוֹךְ הָעִיר וַיִּזְעַק זְעָקָה גְדֹלָה וּמָרָה: וַיָּבוֹא עַד לִפְנֵי שַׁעַר הַמֶּלֶךְ, כִּי אֵין לָבוֹא אֶל שַׁעַר הַמֶּלֶךְ בִּלְבוּשׁ שָׂק: וּבְכָל מְדִינָה וּמְדִינָה מְקוֹם אֲשֶׁר דְּבַר הַמֶּלֶךְ וְדָתוֹ מַגִּיעַ, אֵבֶל גָּדוֹל לַיְּהוּדִים וְצוֹם וּבְכִי וּמִסְפֵּד, שַׂק וָאֵפֶר יֻצַּע לָרַבִּים: וַתָּבוֹאנָה נַעֲרוֹת אֶסְתֵּר וְסָרִיסֶיהָ וַיַּגִּידוּ לָהּ וַתִּתְחַלְחַל הַמַּלְכָּה מְאֹד, וַתִּשְׁלַח בְּגָדִים לְהַלְבִּישׁ אֶת מָרְדֳּכַי וּלְהָסִיר שַׂקּוֹ מֵעָלָיו וְלֹא קִבֵּל: וַתִּקְרָא אֶסְתֵּר לַהֲתָךְ מִסָּרִיסֵי הַמֶּלֶךְ אֲשֶׁר הֶעֱמִיד לְפָנֶיהָ וַתְּצַוֵּהוּ עַל מָרְדֳּכַי, לָדַעַת מַה זֶּה וְעַל מַה זֶּה: וַיֵּצֵא הֲתָךְ אֶל מָרְדֳּכַי, אֶל רְחוֹב הָעִיר אֲשֶׁר לִפְנֵי שַׁעַר הַמֶּלֶךְ: וַיַּגֶּד לוֹ מָרְדֳּכַי אֵת כָּל אֲשֶׁר קָרָהוּ, וְאֵת פָּרָשַׁת הַכֶּסֶף אֲשֶׁר אָמַר הָמָן לִשְׁקוֹל עַל גִּנְזֵי הַמֶּלֶךְ בַּיְּהוּדִים לְאַבְּדָם: וְאֶת פַּתְשֶׁגֶן כְּתָב הַדָּת אֲשֶׁר נִתַּן בְּשׁוּשָׁן לְהַשְׁמִידָם נָתַן לוֹ לְהַרְאוֹת אֶת אֶסְתֵּר וּלְהַגִּיד לָהּ, וּלְצַוּוֹת עָלֶיהָ לָבוֹא אֶל הַמֶּלֶךְ לְהִתְחַנֶּן לוֹ וּלְבַקֵּשׁ מִלְּפָנָיו עַל עַמָּהּ: וַיָּבוֹא הֲתָךְ, וַיַּגֵּד לְאֶסְתֵּר אֵת דִּבְרֵי מָרְדֳּכַי: וַתֹּאמֶר אֶסְתֵּר לַהֲתָךְ, וַתְּצַוֵּהוּ אֶל מָרְדֳּכַי: כָּל עַבְדֵי הַמֶּלֶךְ וְעַם מְדִינוֹת הַמֶּלֶךְ יוֹדְעִים אֲשֶׁר כָּל אִישׁ וְאִשָּׁה אֲשֶׁר יָבוֹא אֶל הַמֶּלֶךְ אֶל הֶחָצֵר הַפְּנִימִית אֲשֶׁר לֹא יִקָּרֵא אַחַת דָּתוֹ לְהָמִית, לְבַד מֵאֲשֶׁר יוֹשִׁיט לוֹ הַמֶּלֶךְ אֶת שַׁרְבִיט הַזָּהָב וְחָיָה, וַאֲנִי לֹא נִקְרֵאתִי לָבוֹא אֶל הַמֶּלֶךְ זֶה שְׁלוֹשִׁים יוֹם: וַיַּגִּידוּ לְמָרְדֳּכַי אֵת דִּבְרֵי אֶסְתֵּר: וַיֹּאמֶר מָרְדֳּכַי לְהָשִׁיב אֶל אֶסְתֵּר, אַל תְּדַמִּי בְנַפְשֵׁךְ לְהִמָּלֵט בֵּית הַמֶּלֶךְ מִכָּל הַיְּהוּדִים: כִּי אִם הַחֲרֵשׁ תַּחֲרִישִׁי בָּעֵת הַזֹּאת, רֶוַח וְהַצָּלָה יַעֲמוֹד לַיְּהוּדִים מִמָּקוֹם אַחֵר וְאַתְּ וּבֵית אָבִיךְ תֹּאבֵדוּ, וּמִי יוֹדֵעַ אִם לְעֵת כָּזֹאת הִגַּעַתְּ לַמַּלְכוּת: וַתֹּאמֶר אֶסְתֵּר לְהָשִׁיב אֶל מָרְדֳּכַי: לֵךְ כְּנוֹס אֶת כָּל הַיְּהוּדִים הַנִּמְצְאִים בְּשׁוּשָׁן וְצוּמוּ עָלַי וְאַל תֹּאכְלוּ וְאַל תִּשְׁתּוּ שְׁלֹשֶׁת יָמִים לַיְלָה וָיוֹם, גַּם אֲנִי וְנַעֲרֹתַי אָצוּם כֵּן, וּבְכֵן אָבוֹא אֶל הַמֶּלֶךְ אֲשֶׁר לֹא כַדָּת וְכַאֲשֶׁר אָבַדְתִּי אָבָדְתִּי: וַיַּעֲבֹר מָרְדֳּכַי, וַיַּעַשׂ כְּכֹל אֲשֶׁר צִוְּתָה עָלָיו אֶסְתֵּר:","cond":["megilatEster"]},{"kind":"header","text":"פרק ה'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ה'","cond":["megilatEster"]},{"kind":"text","text":"וַיְהִי בַּיּוֹם הַשְּׁלִישִׁי וַתִּלְבַּשׁ אֶסְתֵּר מַלְכוּת, וַתַּעֲמֹד בַּחֲצַר בֵּית הַמֶּלֶךְ הַפְּנִימִית נֹכַח בֵּית הַמֶּלֶךְ, וְהַמֶּלֶךְ יוֹשֵׁב עַל כִּסֵּא מַלְכוּתוֹ בְּבֵית הַמַּלְכוּת נֹכַח פֶּתַח הַבָּיִת: וַיְהִי כִרְאוֹת הַמֶּלֶךְ אֶת אֶסְתֵּר הַמַּלְכָּה עֹמֶדֶת בֶּחָצֵר נָשְׂאָה חֵן בְּעֵינָיו, וַיּוֹשֶׁט הַמֶּלֶךְ לְאֶסְתֵּר אֶת שַׁרְבִיט הַזָּהָב אֲשֶׁר בְּיָדוֹ, וַתִּקְרַב אֶסְתֵּר וַתִּגַּע בְּרֹאשׁ הַשַּׁרְבִיט: וַיֹּאמֶר לָהּ הַמֶּלֶךְ מַה לָּךְ אֶסְתֵּר הַמַּלְכָּה, וּמַה בַּקָּשָׁתֵךְ עַד חֲצִי הַמַּלְכוּת וְיִנָּתֵן לָךְ: וַתֹּאמֶר אֶסְתֵּר אִם עַל הַמֶּלֶךְ טוֹב, יָבוֹא הַמֶּלֶךְ וְהָמָן הַיּוֹם אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשִׂיתִי לוֹ: וַיֹּאמֶר הַמֶּלֶךְ מַהֲרוּ אֶת הָמָן לַעֲשׂוֹת אֶת דְּבַר אֶסְתֵּר, וַיָּבֹא הַמֶּלֶךְ וְהָמָן אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשְׂתָה אֶסְתֵּר: וַיֹּאמֶר הַמֶּלֶךְ לְאֶסְתֵּר בְּמִשְׁתֵּה הַיַּיִן מַה שְּׁאֵלָתֵךְ וְיִנָּתֵן לָךְ, וּמַה בַּקָּשָׁתֵךְ עַד חֲצִי הַמַּלְכוּת וְתֵעָשׂ: וַתַּעַן אֶסְתֵּר וַתֹּאמַר, שְׁאֵלָתִי וּבַקָּשָׁתִי: אִם מָצָאתִי חֵן בְּעֵינֵי הַמֶּלֶךְ וְאִם עַל הַמֶּלֶךְ טוֹב לָתֵת אֶת שְׁאֵלָתִי וְלַעֲשׂוֹת אֶת בַּקָּשָׁתִי, יָבוֹא הַמֶּלֶךְ וְהָמָן אֶל הַמִּשְׁתֶּה אֲשֶׁר אֶעֱשֶׂה לָהֶם וּמָחָר אֶעֱשֶׂה כִּדְבַר הַמֶּלֶךְ: וַיֵּצֵא הָמָן בַּיּוֹם הַהוּא שָׂמֵחַ וְטוֹב לֵב, וְכִרְאוֹת הָמָן אֶת מָרְדֳּכַי בְּשַׁעַר הַמֶּלֶךְ וְלֹא קָם וְלֹא זָע מִמֶּנּוּ וַיִּמָּלֵא הָמָן עַל מָרְדֳּכַי חֵמָה: וַיִּתְאַפַּק הָמָן וַיָּבוֹא אֶל בֵּיתוֹ, וַיִּשְׁלַח וַיָּבֵא אֶת אֹהֲבָיו וְאֶת זֶרֶשׁ אִשְׁתּוֹ: וַיְסַפֵּר לָהֶם הָמָן אֶת כְּבוֹד עָשְׁרוֹ וְרֹב בָּנָיו, וְאֵת כָּל אֲשֶׁר גִּדְּלוֹ הַמֶּלֶךְ וְאֵת אֲשֶׁר נִשְּׂאוֹ עַל הַשָּׂרִים וְעַבְדֵי הַמֶּלֶךְ: וַיֹּאמֶר הָמָן, אַף לֹא הֵבִיאָה אֶסְתֵּר הַמַּלְכָּה עִם הַמֶּלֶךְ אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשָׂתָה כִּי אִם אוֹתִי, וְגַם לְמָחָר אֲנִי קָרוּא לָהּ עִם הַמֶּלֶךְ: וְכָל זֶה אֵינֶנּוּ שֹׁוֶה לִי, בְּכָל עֵת אֲשֶׁר אֲנִי רֹאֶה אֶת מָרְדֳּכַי הַיְּהוּדִי יוֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ: וַתֹּאמֶר לוֹ זֶרֶשׁ אִשְׁתּוֹ וְכָל אֹהֲבָיו יַעֲשׂוּ עֵץ גָּבֹהַּ חֲמִשִּׁים אַמָּה, וּבַבֹּקֶר אֱמֹר לַמֶּלֶךְ וְיִתְלוּ אֶת מָרְדֳּכַי עָלָיו וּבֹא עִם הַמֶּלֶךְ אֶל הַמִּשְׁתֶּה שָׂמֵחַ, וַיִּיטַב הַדָּבָר לִפְנֵי הָמָן וַיַּעַשׂ הָעֵץ:","cond":["megilatEster"]},{"kind":"header","text":"פרק ו'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ו'","cond":["megilatEster"]},{"kind":"special","text":"בַּלַּיְלָה הַהוּא נָדְדָה שְׁנַת הַמֶּלֶךְ, וַיֹּאמֶר לְהָבִיא אֶת סֵפֶר הַזִּכְרֹנוֹת דִּבְרֵי הַיָּמִים, וַיִּהְיוּ נִקְרָאִים לִפְנֵי הַמֶּלֶךְ:","cond":["megilatEster"]},{"kind":"text","text":"וַיִּמָּצֵא כָתוּב אֲשֶׁר הִגִּיד מָרְדֳּכַי עַל בִּגְתָנָא וָתֶרֶשׁ שְׁנֵי סָרִיסֵי הַמֶּלֶךְ מִשֹּׁמְרֵי הַסַּף אֲשֶׁר בִּקְשׁוּ לִשְׁלֹחַ יָד בַּמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: וַיֹּאמֶר הַמֶּלֶךְ מַה נַּעֲשָׂה יְקָר וּגְדוּלָּה לְמָרְדֳּכַי עַל זֶה, וַיֹּאמְרוּ נַעֲרֵי הַמֶּלֶךְ מְשָׁרְתָיו לֹא נַעֲשָׂה עִמּוֹ דָּבָר: וַיֹּאמֶר הַמֶּלֶךְ מִי בֶחָצֵר, וְהָמָן בָּא לַחֲצַר בֵּית הַמֶּלֶךְ הַחִיצוֹנָה לֵאמֹר לַמֶּלֶךְ לִתְלוֹת אֶת מָרְדֳּכַי עַל הָעֵץ אֲשֶׁר הֵכִין לוֹ: וַיֹּאמְרוּ נַעֲרֵי הַמֶּלֶךְ אֵלָיו הִנֵּה הָמָן עֹמֵד בֶּחָצֵר, וַיֹּאמֶר הַמֶּלֶךְ יָבוֹא: וַיָּבוֹא הָמָן, וַיֹּאמֶר לוֹ הַמֶּלֶךְ מַה לַעֲשׂוֹת בָּאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ, וַיֹּאמֶר הָמָן בְּלִבּוֹ לְמִי יַחְפֹּץ הַמֶּלֶךְ לַעֲשׂוֹת יְקָר יוֹתֵר מִמֶּנִּי: וַיֹּאמֶר הָמָן אֶל הַמֶּלֶךְ, אִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ: יָבִיאוּ לְבוּשׁ מַלְכוּת אֲשֶׁר לָבַשׁ בּוֹ הַמֶּלֶךְ, וְסוּס אֲשֶׁר רָכַב עָלָיו הַמֶּלֶךְ וַאֲשֶׁר נִתַּן כֶּתֶר מַלְכוּת בְּרֹאשׁוֹ: וְנָתוֹן הַלְּבוּשׁ וְהַסּוּס עַל יַד אִישׁ מִשָּׂרֵי הַמֶּלֶךְ הַפַּרְתְּמִים וְהִלְבִּישׁוּ אֶת הָאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ, וְהִרְכִּיבֻהוּ עַל הַסּוּס בִּרְחוֹב הָעִיר וְקָרְאוּ לְפָנָיו כָּכָה יֵעָשֶׂה לָאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ: וַיֹּאמֶר הַמֶּלֶךְ לְהָמָן מַהֵר קַח אֶת הַלְּבוּשׁ וְאֶת הַסּוּס כַּאֲשֶׁר דִּבַּרְתָּ וַעֲשֵׂה כֵן לְמָרְדֳּכַי הַיְּהוּדִי הַיּוֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ, אַל תַּפֵּל דָּבָר מִכֹּל אֲשֶׁר דִּבַּרְתָּ: וַיִּקַּח הָמָן אֶת הַלְּבוּשׁ וְאֶת הַסּוּס וַיַּלְבֵּשׁ אֶת מָרְדֳּכַי, וַיַּרְכִּיבֵהוּ בִּרְחוֹב הָעִיר וַיִּקְרָא לְפָנָיו כָּכָה יֵעָשֶׂה לָאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ: וַיָּשָָב מָרְדֳּכַי אֶל שַׁעַר הַמֶּלֶךְ, וְהָמָן נִדְחַף אֶל בֵּיתוֹ אָבֵל וַחֲפוּי רֹאשׁ: וַיְסַפֵּר הָמָן לְזֶרֶשׁ אִשְׁתּוֹ וּלְכָל אֹהֲבָיו אֵת כָּל אֲשֶׁר קָרָהוּ, וַיֹּאמְרוּ לּוֹ חֲכָמָיו וְזֶרֶשׁ אִשְׁתּוֹ אִם מִזֶּרַע הַיְּהוּדִים מָרְדֳּכַי אֲשֶׁר הַחִלּוֹתָ לִנְפֹּל לְפָנָיו לֹא תוּכַל לוֹ, כִּי נָפוֹל תִּפּוֹל לְפָנָיו: עוֹדָם מְדַבְּרִים עִמּוֹ וְסָרִיסֵי הַמֶּלֶךְ הִגִּיעוּ, וַיַּבְהִלוּ לְהָבִיא אֶת הָמָן אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשְׂתָה אֶסְתֵּר:","cond":["megilatEster"]},{"kind":"header","text":"פרק ז'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ז'","cond":["megilatEster"]},{"kind":"text","text":"וַיָּבֹא הַמֶּלֶךְ וְהָמָן לִשְׁתּוֹת עִם אֶסְתֵּר הַמַּלְכָּה: וַיֹּאמֶר הַמֶּלֶךְ לְאֶסְתֵּר גַּם בַּיּוֹם הַשֵּׁנִי בְּמִשְׁתֵּה הַיַּיִן מַה שְּׁאֵלָתֵךְ אֶסְתֵּר הַמַּלְכָּה וְתִנָּתֵן לָךְ, וּמַה בַּקָּשָׁתֵךְ עַד חֲצִי הַמַּלְכוּת וְתֵעָשׂ: וַתַּעַן אֶסְתֵּר הַמַּלְכָּה וַתֹּאמַר אִם מָצָאתִי חֵן בְּעֵינֶיךָ הַמֶּלֶךְ וְאִם עַל הַמֶּלֶךְ טוֹב, תִּנָּתֶן לִי נַפְשִׁי בִּשְׁאֵלָתִי וְעַמִּי בְּבַקָּשָׁתִי: כִּי נִמְכַּרְנוּ אֲנִי וְעַמִּי לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד, וְאִלּוּ לַעֲבָדִים וְלִשְׁפָחוֹת נִמְכַּרְנוּ הֶחֱרַשְׁתִּי כִּי אֵין הַצָּר שֹׁוֶה בְּנֵזֶק הַמֶּלֶךְ: וַיֹּאמֶר הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ וַיֹּאמֶר לְאֶסְתֵּר הַמַּלְכָּה, מִי הוּא זֶה וְאֵי זֶה הוּא אֲשֶׁר מְלָאוֹ לִבּוֹ לַעֲשׂוֹת כֵּן: וַתֹּאמֶר אֶסְתֵּר אִישׁ צַר וְאוֹיֵב הָמָן הָרָע הַזֶּה, וְהָמָן נִבְעַת מִלִּפְנֵי הַמֶּלֶךְ וְהַמַּלְכָּה: וְהַמֶּלֶךְ קָם בַּחֲמָתוֹ מִמִּשְׁתֵּה הַיַּיִן אֶל גִּנַּת הַבִּיתָן, וְהָמָן עָמַד לְבַקֵּשׁ עַל נַפְשׁוֹ מֵאֶסְתֵּר הַמַּלְכָּה כִּי רָאָה כִּי כָלְתָה אֵלָיו הָרָעָה מֵאֵת הַמֶּלֶךְ: וְהַמֶּלֶךְ שָׁב מִגִּנַּת הַבִּיתָן אֶל בֵּית מִשְׁתֵּה הַיַּיִן וְהָמָן נֹפֵל עַל הַמִּטָּה אֲשֶׁר אֶסְתֵּר עָלֶיהָ, וַיֹּאמֶר הַמֶּלֶךְ הֲגַם לִכְבּוֹשׁ אֶת הַמַּלְכָּה עִמִּי בַּבָּיִת, הַדָּבָר יָצָא מִפִּי הַמֶּלֶךְ וּפְנֵי הָמָן חָפוּ: וַיֹּאמֶר חַרְבוֹנָה אֶחָד מִן הַסָּרִיסִים לִפְנֵי הַמֶּלֶךְ גַּם הִנֵּה הָעֵץ אֲשֶׁר עָשָׂה הָמָן לְמָרְדֳּכַי אֲשֶׁר דִּבֶּר טוֹב עַל הַמֶּלֶךְ עֹמֵד בְּבֵית הָמָן גָּבֹהַּ חֲמִשִּׁים אַמָּה, וַיֹּאמֶר הַמֶּלֶךְ תְּלֻהוּ עָלָיו: וַיִּתְלוּ אֶת הָמָן עַל הָעֵץ אֲשֶׁר הֵכִין לְמָרְדֳּכַי, וַחֲמַת הַמֶּלֶךְ שָׁכָכָה:","cond":["megilatEster"]},{"kind":"header","text":"פרק ח'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ח'","cond":["megilatEster"]},{"kind":"text","text":"בַּיּוֹם הַהוּא נָתַן הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ לְאֶסְתֵּר הַמַּלְכָּה אֶת בֵּית הָמָן צֹרֵר הַיְּהוּדִים, וּמָרְדֳּכַי בָּא לִפְנֵי הַמֶּלֶךְ כִּי הִגִּידָה אֶסְתֵּר מַה הוּא לָהּ: וַיָּסַר הַמֶּלֶךְ אֶת טַבַּעְתּוֹ אֲשֶׁר הֶעֱבִיר מֵהָמָן וַיִּתְּנָהּ לְמָרְדֳּכַי, וַתָּשֶׂם אֶסְתֵּר אֶת מָרְדֳּכַי עַל בֵּית הָמָן: וַתּוֹסֶף אֶסְתֵּר וַתְּדַבֵּר לִפְנֵי הַמֶּלֶךְ וַתִּפֹּל לִפְנֵי רַגְלָיו, וַתֵּבְךְּ וַתִּתְחַנֶּן לוֹ לְהַעֲבִיר אֶת רָעַת הָמָן הָאֲגָגִי וְאֵת מַחֲשַׁבְתּוֹ אֲשֶׁר חָשַׁב עַל הַיְּהוּדִים: וַיּוֹשֶׁט הַמֶּלֶךְ לְאֶסְתֵּר אֵת שַׁרְבִט הַזָּהָב, וַתָּקָם אֶסְתֵּר וַתַּעֲמֹד לִפְנֵי הַמֶּלֶךְ: וַתֹּאמֶר אִם עַל הַמֶּלֶךְ טוֹב וְאִם מָצָאתִי חֵן לְפָנָיו וְכָשֵׁר הַדָּבָר לִפְנֵי הַמֶּלֶךְ וְטוֹבָה אֲנִי בְּעֵינָיו, יִכָּתֵב לְהָשִׁיב אֶת הַסְּפָרִים מַחֲשֶׁבֶת הָמָן בֶּן הַמְּדָתָא הָאֲגָגִי אֲשֶׁר כָּתַב לְאַבֵּד אֶת הַיְּהוּדִים אֲשֶׁר בְּכָל מְדִינוֹת הַמֶּלֶךְ: כִּי אֵיכָכָה אוּכַל וְרָאִיתִי בָּרָעָה אֲשֶׁר יִמְצָא אֶת עַמִּי, וְאֵיכָכָה אוּכַל וְרָאִיתִי בְּאָבְדַן מוֹלַדְתִּי: וַיֹּאמֶר הַמֶּלֶךְ אֲחַשְׁוֵרֹשׁ לְאֶסְתֵּר הַמַּלְכָּה וּלְמָרְדֳּכַי הַיְּהוּדִי, הִנֵּה בֵית הָמָן נָתַתִּי לְאֶסְתֵּר וְאֹתוֹ תָּלוּ עַל הָעֵץ עַל אֲשֶׁר שָׁלַח יָדוֹ בַּיְּהוּדִים: וְאַתֶּם כִּתְבוּ עַל הַיְּהוּדִים כַּטּוֹב בְּעֵינֵיכֶם בְּשֵׁם הַמֶּלֶךְ וְחִתְמוּ בְּטַבַּעַת הַמֶּלֶךְ, כִּי כְתָב אֲשֶׁר נִכְתָּב בְּשֵׁם הַמֶּלֶךְ וְנַחְתּוֹם בְּטַבַּעַת הַמֶּלֶךְ אֵין לְהָשִׁיב: וַיִּקָּרְאוּ סֹפְרֵי הַמֶּלֶךְ בָּעֵת הַהִיא בַּחֹדֶשׁ הַשְּׁלִישִׁי הוּא חֹדֶשׁ סִיוָן בִּשְׁלוֹשָׁה וְעֶשְׂרִים בּוֹ, וַיִּכָּתֵב כְּכָל אֲשֶׁר צִוָּה מָרְדֳּכַי אֶל הַיְּהוּדִים וְאֶל הָאֲחַשְׁדַּרְפְּנִים וְהַפַּחוֹת וְשָׂרֵי הַמְּדִינוֹת אֲשֶׁר מֵהֹדּוּ וְעַד כּוּשׁ, שֶׁבַע וְעֶשְׂרִים וּמֵאָה מְדִינָה, מְדִינָה וּמְדִינָה כִּכְתָבָהּ וְעַם וָעָם כִּלְשֹׁנוֹ, וְאֶל הַיְּהוּדִים כִּכְתָבָם וְכִלְשׁוֹנָם: וַיִּכְתֹּב בְּשֵׁם הַמֶּלֶךְ אֲחַשְׁוֵרֹשׁ וַיַּחְתֹּם בְּטַבַּעַת הַמֶּלֶךְ, וַיִּשְׁלַח סְפָרִים בְּיַד הָרָצִים בַּסּוּסִים רֹכְבֵי הָרֶכֶשׁ הָאֲחַשְׁתְּרָנִים בְּנֵי הָרַמָּכִים: אֲשֶׁר נָתַן הַמֶּלֶךְ לַיְּהוּדִים אֲשֶׁר בְּכָל עִיר וָעִיר לְהִקָּהֵל וְלַעֲמֹד עַל נַפְשָׁם, לְהַשְׁמִיד וְלַהֲרֹג וּלְאַבֵּד אֶת כָּל חֵיל עַם וּמְדִינָה הַצָּרִים אֹתָם טַף וְנָשִׁים, וּשְׁלָלָם לָבוֹז: בְּיוֹם אֶחָד בְּכָל מְדִינוֹת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, בִּשְׁלוֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר: פַּתְשֶׁגֶן הַכְּתָב לְהִנָּתֵן דָּת בְּכָל מְדִינָה וּמְדִינָה גָּלוּי לְכָל הָעַמִּים, וְלִהְיוֹת הַיְּהוּדִים עֲתִידִים לַיּוֹם הַזֶּה לְהִנָּקֵם מֵאֹיְבֵיהֶם: הָרָצִים רֹכְבֵי הָרֶכֶשׁ הָאֲחַשְׁתְּרָנִים יָצְאוּ מְבֹהָלִים וּדְחוּפִים בִּדְבַר הַמֶּלֶךְ, וְהַדָּת נִתְּנָה בְּשׁוּשַׁן הַבִּירָה:","cond":["megilatEster"]},{"kind":"special","text":"וּמָרְדֳּכַי יָצָא מִלִּפְנֵי הַמֶּלֶךְ בִּלְבוּשׁ מַלְכוּת תְּכֵלֶת וָחוּר וַעֲטֶרֶת זָהָב גְּדוֹלָה וְתַכְרִיךְ בּוּץ וְאַרְגָּמָן, וְהָעִיר שׁוּשָׁן צָהֲלָה וְשָׂמֵחָה: לַיְּהוּדִים הָיְתָה אוֹרָה וְשִׂמְחָה, וְשָׂשֹׂן וִיקָר:","cond":["megilatEster"]},{"kind":"text","text":"וּבְכָל מְדִינָה וּמְדִינָה וּבְכָל עִיר וָעִיר, מְקוֹם אֲשֶׁר דְּבַר הַמֶּלֶךְ וְדָתוֹ מַגִּיעַ, שִׂמְחָה וְשָׂשׂוֹן לַיְּהוּדִים מִשְׁתֶּה וְיוֹם טוֹב, וְרַבִּים מֵעַמֵּי הָאָרֶץ מִתְיַהֲדִים כִּי נָפַל פַּחַד הַיְּהוּדִים עֲלֵיהֶם:","cond":["megilatEster"]},{"kind":"header","text":"פרק ט'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ט'","cond":["megilatEster"]},{"kind":"text","text":"וּבִשְׁנֵים עָשָׂר חֹדֶשׁ הוּא חֹדֶשׁ אֲדָר בִּשְׁלוֹשָׁה עָשָׂר יוֹם בּוֹ אֲשֶׁר הִגִּיעַ דְּבַר הַמֶּלֶךְ וְדָתוֹ לְהֵעָשׂוֹת, בַּיּוֹם אֲשֶׁר שִׂבְּרוּ אֹיְבֵי הַיְּהוּדִים לִשְׁלוֹט בָּהֶם וְנַהֲפוֹךְ הוּא אֲשֶׁר יִשְׁלְטוּ הַיְּהוּדִים הֵמָּה בְּשֹׂנְאֵיהֶם: נִקְהֲלוּ הַיְּהוּדִים בְּעָרֵיהֶם בְּכָל מְדִינוֹת הַמֶּלֶךְ אֳחַשְׁוֵרוֹשׁ לִשְׁלֹחַ יָד בִּמְבַקְשֵׁי רָעָתָם, וְאִישׁ לֹא עָמַד לִפְנֵיהֶם כִּי נָפַל פַּחְדָּם עַל כָּל הָעַמִּים: וְכָל שָׂרֵי הַמְּדִינוֹת וְהָאֲחַשְׁדַּרְפְּנִים וְהַפַּחוֹת וְעֹשֵׂי הַמְּלָאכָה אֲשֶׁר לַמֶּלֶךְ מְנַשְּׂאִים אֶת הַיְּהוּדִים, כִּי נָפַל פַּחַד מָרְדֳּכַי עֲלֵיהֶם: כִּי גָדוֹל מָרְדֳּכַי בְּבֵית הַמֶּלֶךְ וְשָׁמְעוֹ הוֹלֵךְ בְּכָל הַמְּדִינוֹת, כִּי הָאִישׁ מָרְדֳּכַי הוֹלֵךְ וְגָדוֹל: וַיַּכּוּ הַיְּהוּדִים בְּכָל אֹיְבֵיהֶם מַכַּת חֶרֶב וְהֶרֶג וְאַבְדָן, וַיַּעֲשׂוּ בְשֹׂנְאֵיהֶם כִּרְצוֹנָם: וּבְשׁוּשַׁן הַבִּירָה הָרְגוּ הַיְּהוּדִים וְאַבֵּד חֲמֵשׁ מֵאוֹת אִישׁ: וְאֵת פַּרְשַׁנְדָּתָא וְאֵת דַּלְפוֹן וְאֵת אַסְפָּתָא: וְאֵת פּוֹרָתָא וְאֵת אֲדַלְיָא וְאֵת אֲרִידָתָא: וְאֵת פַּרְמַשְׁתָּא וְאֵת אֲרִיסַי וְאֵת אֲרִדַי וְאֵת וַיְזָתָא: עֲשֶׂרֶת בְּנֵי הָמָן בֶּן הַמְּדָתָא צֹרֵר הַיְּהוּדִים הָרָגוּ, וּבַבִּזָּה לֹא שָׁלְחוּ אֶת יָדָם: בַּיּוֹם הַהוּא בָּא מִסְפַּר הַהֲרוּגִים בְּשׁוּשַׁן הַבִּירָה לִפְנֵי הַמֶּלֶךְ: וַיֹּאמֶר הַמֶּלֶךְ לְאֶסְתֵּר הַמַּלְכָּה בְּשׁוּשַׁן הַבִּירָה הָרְגוּ הַיְּהוּדִים וְאַבֵּד חֲמֵשׁ מֵאוֹת אִישׁ וְאֵת עֲשֶׂרֶת בְּנֵי הָמָן, בִּשְׁאָר מְדִינוֹת הַמֶּלֶךְ מֶה עָשׂוּ, וּמַה שְּׁאֵלָתֵךְ וְיִנָּתֵן לָךְ וּמַה בַּקָּשָׁתֵךְ עוֹד וְתֵעָשׂ: וַתֹּאמֶר אֶסְתֵּר אִם עַל הַמֶּלֶךְ טוֹב, יִנָּתֵן גַּם מָחָר לַיְּהוּדִים אֲשֶׁר בְּשׁוּשָׁן לַעֲשׂוֹת כְּדָת הַיּוֹם, וְאֵת עֲשֶׂרֶת בְּנֵי הָמָן יִתְלוּ עַל הָעֵץ: וַיֹּאמֶר הַמֶּלֶךְ לְהֵעָשׂוֹת כֵּן וַתִּנָּתֵן דָּת בְּשׁוּשָׁן, וְאֵת עֲשֶׂרֶת בְּנֵי הָמָן תָּלוּ: וַיִּקָּהֲלוּ הַיְּהוּדִים אֲשֶׁר בְּשׁוּשָׁן גַּם בְּיוֹם אַרְבָּעָה עָשָׂר לְחֹדֶשׁ אֲדָר וַיַּהַרְגוּ בְשׁוּשָׁן שְׁלֹשׁ מֵאוֹת אִישׁ, וּבַבִּזָּה לֹא שָׁלְחוּ אֶת יָדָם: וּשְׁאָר הַיְּהוּדִים אֲשֶׁר בִּמְדִינוֹת הַמֶּלֶךְ נִקְהֲלוּ וְעָמֹד עַל נַפְשָׁם וְנוֹחַ מֵאֹיְבֵיהֶם וְהָרֹג בְּשֹׂנְאֵיהֶם חֲמִשָּׁה וְשִׁבְעִים אָלֶף, וּבַבִּזָּה לֹא שָׁלְחוּ אֶת יָדָם: בְּיוֹם שְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ אֲדָר, וְנוֹחַ בְּאַרְבָּעָה עָשָׂר בּוֹ וְעָשֹׂה אֹתוֹ יוֹם מִשְׁתֶּה וְשִׂמְחָה: וְהַיְּהוּדִים אֲשֶׁר בְּשׁוּשָׁן נִקְהֲלוּ בִּשְׁלֹשָׁה עָשָׂר בּוֹ וּבְאַרְבָּעָה עָשָׂר בּוֹ, וְנוֹחַ בַּחֲמִשָּׁה עָשָׂר בּוֹ וְעָשֹׂה אֹתוֹ יוֹם מִשְׁתֶּה וְשִׂמְחָה: עַל כֵּן הַיְּהוּדִים הַפְּרָזִים הַיֹּשְׁבִים בְּעָרֵי הַפְּרָזוֹת, עֹשִׂים אֵת יוֹם אַרְבָּעָה עָשָׂר לְחֹדֶשׁ אֲדָר שִׂמְחָה וּמִשְׁתֶּה וְיוֹם טוֹב, וּמִשְׁלוֹחַ מָנוֹת אִישׁ לְרֵעֵהוּ: וַיִּכְתֹּב מָרְדֳּכַי אֶת הַדְּבָרִים הָאֵלֶּה, וַיִּשְׁלַח סְפָרִים אֶל כָּל הַיְּהוּדִים אֲשֶׁר בְּכָל מְדִינוֹת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ הַקְּרוֹבִים וְהָרְחוֹקִים: לְקַיֵּם עֲלֵיהֶם, לִהְיוֹת עֹשִׂים אֵת יוֹם אַרְבָּעָה עָשָׂר לְחֹדֶשׁ אֲדָר וְאֵת יוֹם חֲמִשָּׁה עָשָׂר בּוֹ, בְּכָל שָׁנָה וְשָׁנָה: כַּיָּמִים אֲשֶׁר נָחוּ בָהֶם הַיְּהוּדִים מֵאוֹיְבֵיהֶם, וְהַחֹדֶשׁ אֲשֶׁר נֶהְפַּךְ לָהֶם מִיָּגוֹן לְשִׂמְחָה וּמֵאֵבֶל לְיוֹם טוֹב, לַעֲשׂוֹת אוֹתָם יְמֵי מִשְׁתֶּה וְשִׂמְחָה וּמִשְׁלוֹחַ מָנוֹת אִישׁ לְרֵעֵהוּ וּמַתָּנוֹת לָאֶבְיוֹנִים: וְקִבֵּל הַיְּהוּדִים אֵת אֲשֶׁר הֵחֵלּוּ לַעֲשׂוֹת, וְאֵת אֲשֶׁר כָּתַב מָרְדֳּכַי אֲלֵיהֶם: כִּי הָמָן בֶּן הַמְּדָתָא הָאֲגָגִי צֹרֵר כָּל הַיְּהוּדִים חָשַׁב עַל הַיְּהוּדִים לְאַבְּדָם, וְהִפִּיל פּוּר הוּא הַגּוֹרָל לְהֻמָּם וּלְאַבְּדָם: וּבְבֹאָהּ לִפְנֵי הַמֶּלֶךְ, אָמַר עִם הַסֵּפֶר יָשׁוּב מַחֲשַׁבְתּוֹ הָרָעָה אֲשֶׁר חָשַׁב עַל הַיְּהוּדִים עַל רֹאשׁוֹ, וְתָלוּ אֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ: עַל כֵּן קָרְאוּ לַיָּמִים הָאֵלֶּה פוּרִים עַל שֵׁם הַפּוּר, עַל כֵּן עַל כָּל דִּבְרֵי הָאִגֶּרֶת הַזֹּאת, וּמָה רָאוּ עַל כָּכָה וּמָה הִגִּיעַ אֲלֵיהֶם: קִיְּמוּ וְקִבְּלוּ הַיְּהוּדִים עֲלֵיהֶם וְעַל זַרְעָם וְעַל כָּל הַנִּלְוִים עֲלֵיהֶם וְלֹא יַעֲבוֹר, לִהְיוֹת עֹשִׂים אֵת שְׁנֵי הַיָּמִים הָאֵלֶּה כִּכְתָבָם וְכִזְמַנָּם, בְּכָל שָׁנָה וְשָׁנָה: וְהַיָּמִים הָאֵלֶּה נִזְכָּרִים וְנַעֲשִׂים בְּכָל דּוֹר וָדוֹר מִשְׁפָּחָה וּמִשְׁפָּחָה מְדִינָה וּמְדִינָה וְעִיר וָעִיר, וִימֵי הַפּוּרִים הָאֵלֶּה לֹא יַעַבְרוּ מִתּוֹךְ הַיְּהוּדִים וְזִכְרָם לֹא יָסוּף מִזַּרְעָם: וַתִּכְתֹּב אֶסְתֵּר הַמַּלְכָּה בַת אֲבִיחַיִל וּמָרְדֳּכַי הַיְּהוּדִי אֶת כָּל תֹּקֶף, לְקַיֵּם אֵת אִגֶּרֶת הַפּוּרִים הַזֹּאת הַשֵּׁנִית: וַיִּשְׁלַח סְפָרִים אֶל כָּל הַיְּהוּדִים, אֶל שֶׁבַע וְעֶשְׂרִים וּמֵאָה מְדִינָה מַלְכוּת אֲחַשְׁוֵרוֹשׁ, דִּבְרֵי שָׁלוֹם וֶאֱמֶת: לְקַיֵּם אֵת יְמֵי הַפֻּרִים הָאֵלֶּה בִּזְמַנֵּיהֶם כַּאֲשֶׁר קִיַּם עֲלֵיהֶם מָרְדֳּכַי הַיְּהוּדִי וְאֶסְתֵּר הַמַּלְכָּה וְכַאֲשֶׁר קִיְּמוּ עַל נַפְשָׁם וְעַל זַרְעָם, דִּבְרֵי הַצֹּמוֹת וְזַעֲקָתָם: וּמַאֲמַר אֶסְתֵּר קִיַּם דִּבְרֵי הַפֻּרִים הָאֵלֶּה, וְנִכְתָּב בַּסֵּפֶר:","cond":["megilatEster"]},{"kind":"header","text":"פרק י'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק י'","cond":["megilatEster"]},{"kind":"text","text":"וַיָּשֶׂם הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ מַס עַל הָאָרֶץ וְאִיֵּי הַיָּם: וְכָל מַעֲשֵׂה תָקְפּוֹ וּגְבוּרָתוֹ, וּפָרָשַׁת גְּדֻלַּת מָרְדֳּכַי אֲשֶׁר גִּדְּלוֹ הַמֶּלֶךְ, הֲלוֹא הֵם כְּתוּבִים עַל סֵפֶר דִּבְרֵי הַיָּמִים לְמַלְכֵי מָדַי וּפָרָס:","cond":["megilatEster"]},{"kind":"special","text":"כִּי מָרְדֳּכַי הַיְּהוּדִי מִשְׁנֶה לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ וְגָדוֹל לַיְּהוּדִים וְרָצוּי לְרֹב אֶחָיו, דֹּרֵשׁ טוֹב לְעַמּוֹ וְדֹבֵר שָׁלוֹם לְכָל זַרְעוֹ:","cond":["megilatEster"]},{"kind":"header","text":"ברכת הרב את ריבנו","cond":["megilatEster"]},{"kind":"instruction","text":"ברכת הרב את ריבנו מברכים גם ביום וגם בלילה, ומברכים אותה רק בציבור של עשרה. ברכה זו מברך רק החזן הקורא את המגילה לאחר שכרך את כל המגילה.","cond":["megilatEster"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הָרָב אֶת רִיבֵנוּ, וְהַדָּן אֶת דִּינֵנוּ, וְהַנּוֹקֵם אֶת נִקְמָתֵנוּ, וְהַמְשַׁלֵּם גְּמוּל לְכָל אוֹיְבֵי נַפְשֵׁנוּ, וְהַנִּפְרָע לָנוּ מִצָּרֵינוּ. בָּרוּךְ אַתָּה יהוה, הַנִּפְרָע לְעַמּוֹ יִשְׂרָאֵל מִכָּל צָרֵיהֶם, הָאֵל הַמּוֹשִׁיעַ.","cond":["megilatEster"]},{"kind":"header","text":"אשר הניא","cond":["megilatEster"]},{"kind":"instruction","text":"אשר הניא\n\nבשחרית מתחילים משושנת יעקב. ויש נוהגים לומר \"אשר הניא\" אף בשחרית, אם אין אומרים פיוטים בחזרת הש\"ץ.","cond":["megilatEster"]},{"kind":"text","text":"אֲשֶׁר הֵנִיא עֲצַת גּוֹיִם, וַיָּפֶר מַחְשְׁבוֹת עֲרוּמִים.\nבְּקוּם עָלֵינוּ אָדָם רָשָׁע, נֵצֶר זָדוֹן מִזֶּרַע עֲמָלֵק.\nגָּאָה בְעָשְׁרוֹ וְכָרָה לוֹ בּוֹר, וּגְדֻלָּתוֹ יָקְשָׁה לּוֹ לָכֶד.\nדִּמָּה בְנַפְשׁוֹ לִלְכֹּד וְנִלְכַּד, בִּקֵּשׁ לְהַשְׁמִיד וְנִשְׁמַד מְהֵרָה.\nהָמָן הוֹדִיעַ אֵיבַת אֲבוֹתָיו, וְעוֹרֵר שִׂנְאַת אַחִים לַבָּנִים.\nוְלֹא זָכַר רַחֲמֵי שָׁאוּל, כִּי בְחֶמְלָתוֹ עַל אֲגָג נוֹלַד אוֹיֵב.\nזָמַם רָשָׁע לְהַכְרִית צַדִּיק, וְנִלְכַּד טָמֵא בִּידֵי טָהוֹר.\nחֶסֶד גָּבַר עַל שִׁגְגַת אָב, וְרָשָׁע הוֹסִיף חֵטְא עַל חֲטָאָיו.\nטָמַן בְּלִבּוֹ מַחְשְׁבוֹת עֲרוּמָיו, וַיִּתְמַכֵּר לַעֲשׂוֹת רָעָה.\nיָדוֹ שָׁלַח בִּקְדוֹשֵׁי אֵל, כַּסְפּוֹ נָתַן לְהַכְרִית זִכְרָם.\nכִּרְאוֹת מָרְדֳּכַי כִּי יָצָא קֶצֶף, וְדָתֵי הָמָן נִתְּנוּ בְשׁוּשָׁן.\nלָבַשׁ שַׂק וְקָשַׁר מִסְפֵּד, וְגָזַר צוֹם וַיֵּשֶׁב עַל הָאֵפֶר.\nמִי זֶה יַעֲמֹד לְכַפֵּר שְׁגָגָה, וְלִמְחֹל חַטַּאת עֲוׂן אֲבוֹתֵינוּ.\nנֵץ פָּרַח מִלּוּלָב, הֵן הֲדַסָּה עָמְדָה לְעוֹרֵר יְשֵׁנִים.\nסָרִיסֶיהָ הִבְהִילוּ לְהָמָן, לְהַשְׁקוֹתוֹ יֵין חֲמַת תַּנִּינִים.\nעָמַד בְּעָשְׁרוֹ וְנָפַל בְּרִשְׁעוֹ, עָשָׂה לוֹ עֵץ וְנִתְלָה עָלָיו.\nפִּיהֶם פָּתְחוּ כָָּל יוֹשְׁבֵי תֵבֵל, כִּי פוּר הָמָן נֶהְפַּךְ לְפוּרֵנוּ.\nצַדִּיק נֶחֱלַץ מִיַּד רָשָׁע, אוֹיֵב נִתַּן תַּחַת נַפְשׁוֹ.\nקִיְּמוּ עֲלֵיהֶם לַעֲשׂוֹת פּוּרִים, וְלִשְׂמֹחַ בְּכָל שָׁנָה וְשָׁנָה.\nרָאִיתָ אֶת תְּפִלַּת מָרְדֳּכַי וְאֶסְתֵּר, הָמָן וּבָנָיו עַל הָעֵץ תָּלִיתָ.","cond":["megilatEster"]},{"kind":"header","text":"שושנת יעקב","cond":["megilatEster"]},{"kind":"text","text":"שׁוֹשַׁנַּת יַעֲקֹב צָהֲלָה וְשָׂמֵחָה, בִּרְאוֹתָם יַחַד תְּכֵלֶת מָרְדֳּכָי.\nתְּשׁוּעָתָם הָיִיתָ לָנֶצַח, וְתִקְוָתָם בְּכָל דּוֹר וָדוֹר.\nלְהוֹדִיעַ שֶׁכָּל קֹוֶיךָ לֹא יֵבֹשׁוּ, וְלֹא יִכָּלְמוּ לָנֶצַח כָּל הַחוֹסִים בָּךְ.\nאָרוּר הָמָן אֲשֶׁר בִּקֵשׁ לְאַבְּדִי. בָּרוּךְ מָרְדֳּכַי הַיְּהוּדִי.\nאֲרוּרָה זֶרֶשׁ אֵשֶׁת מַפְחִידִי. בְּרוּכָה אֶסְתֵּר [מְגִנָּה] בַּעֲדִי.\nאֲרוּרִים כָּל הָרְשָׁעִים. בְּרוּכִים כָּל הַצַּדִּיקִים.\nוְגַם חַרְבוֹנָה זָכוּר לַטּוֹב.","cond":["megilatEster"]},{"kind":"header","text":"ואתה קדוש","cond":["megilatEster"]},{"kind":"text","text":"וְאַתָּה קָדוֹשׁ יוֹשֵׁב תְּהִלּוֹת יִשְׂרָאֵל: וְקָרָא זֶה אֶל זֶה וְאָמַר: קָדוֹשׁ, קָדוֹשׁ, קָדוֹשׁ יהוה צְבָאוֹת, מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ: וּמְקַבְּלִין דֵּין מִן דֵּין וְאָמְרִין: קַדִּישׁ בִּשְׁמֵי מֵרוֹמַא עִלָאַה בֵּית שְׁכִינְתֵּהּ, קַדִּישׁ עַל אַרְעָא עוֹבַד גְּבוּרְתֵּהּ, קַדִּישׁ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא, יהוה צְבָאוֹת מַלְיָא כָל אַרְעָא זִיו יְקָרֵהּ. וַתִּשָּׂאֵנִי רוּחַ, וָאֶשְׁמַע אַחֲרַי קוֹל רַעַשׁ גָּדוֹל: בָּרוּךְ כְּבוֹד יהוה מִמְּקוֹמוֹ: וּנְטָלַתְנִי רוּחָא, וּשְׁמָעִית בַּתְרַי קַל זִיעַ שַׂגִּיא דִמְשַׁבְּחִין וְאָמְרִין: בְּרִיךְ יְקָרָא דַיהוה מֵאֲתָר בֵּית שְׁכִינְתֵּהּ. יהוה יִמְלֹךְ לְעוֹלָם וָעֶד: יהוה מַלְכוּתֵיהּ קָאֵים לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\n\nיהוה אֱלֹהֵי אַבְרָהָם יִצְחָק וְיִשְׂרָאֵל אֲבוֹתֵינוּ, שָׁמְרָה זֹּאת לְעוֹלָם, לְיֵצֶר מַחְשְׁבוֹת לְבַב עַמֶּךָ, וְהָכֵן לְבָבָם אֵלֶיךָ: וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית, וְהִרְבָּה לְהָשִׁיב אַפּוֹ, וְלֹא יָעִיר כָּל חֲמָתוֹ: כִּי אַתָּה יהוה טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קוֹרְאֶיךָ: צִדְקָתְךָ צֶּדֶק לְעוֹלָם, וְתוֹרָתְךָ אֱמֶת: תִּתֵּן אֱמֶת לְיַעֲקֹב, חֶסֶד לְאַבְרָהָם, אֲשֶׁר נִשְׁבַּעְתָּ לַאֲבֹתֵינוּ מִימֵי קֶדֶם: בָּרוּךְ אֲדֹנָי יוֹם יוֹם, יַעֲמָס לָנוּ הָאֵל יְשׁוּעָתֵנוּ, סֶלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב, סֶלָה: יהוה צְבָאוֹת אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ: בָּרוּךְ הוּא אֱלֹהֵינוּ שֶׁבְּרָאָנוּ לִכְבוֹדוֹ, וְהִבְדִּילָנוּ מִן הַתּוֹעִים, וְנָתַן לָנוּ תּוֹרַת אֱמֶת, וְחַיֵּי עוֹלָם נָטַע בְּתוֹכֵנוּ. הוּא יִפְתַּח לִבֵּנוּ בְּתוֹרָתוֹ, וְיָשֵׂם בְּלִבֵּנוּ אַהֲבָתוֹ וְיִרְאָתוֹ וְלַעֲשׂוֹת רְצוֹנוֹ וּלְעָבְדוֹ בְּלֵבָב שָׁלֵם. לְמַעַן לֹא נִיגַע לָרִיק, וְלֹא נֵלֵד לַבֶּהָלָה. יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁנִּשְׁמֹר חֻקֶּיךָ בָּעוֹלָם הַזֶּה, וְנִזְכֶּה וְנִחְיֶה וְנִרְאֶה וְנִירַשׁ טוֹבָה וּבְרָכָה לִשְׁנֵי יְמוֹת הַמָּשִׁיחַ וּלְחַיֵּי הָעוֹלָם הַבָּא. לְמַעַן יְזַמֶּרְךָ כָבוֹד וְלֹא יִדֹּם, יהוה אֱלֹהַי לְעוֹלָם אוֹדֶךָּ: בָּרוּךְ הַגֶּבֶר אֲשֶׁר יִבְטַח בַּיהוה, וְהָיָה יהוה מִבְטַחוֹ: בִּטְחוּ בַיהוה עֲדֵי עַד, כִּי בְּיָהּ יהוה צוּר עוֹלָמִים: וְיִבְטְחוּ בְךָ יוֹדְעֵי שְׁמֶךָ, כִּי לֹא עָזַבְתָּ דֹּרְשֶׁיךָ יהוה: יהוה חָפֵץ לְמַעַן צִדְקוֹ, יַגְדִּיל תּורָה וְיַאְדִּיר: יהוה אֲדֹנֵינוּ, מָה אַדִּיר שִׁמְךָ בְּכָל הָאָרֶץ: חִזְקוּ וְיַאֲמֵץ לְבַבְכֶם כָּל הַמְיַחֲלִים לַיהוה:","cond":["megilatEster"]},{"kind":"instruction","text":"מברך לאור הנר:","cond":["tishaaBeavFire"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא מְאוֹרֵי הָאֵשׁ.","cond":["tishaaBeavFire"]},{"kind":"header","text":"ואתה קדוש","cond":["tishaaBeav"]},{"kind":"text","text":"וְאַתָּה קָדוֹשׁ יוֹשֵׁב תְּהִלּוֹת יִשְׂרָאֵל: וְקָרָא זֶה אֶל זֶה וְאָמַר: קָדוֹשׁ, קָדוֹשׁ, קָדוֹשׁ יהוה צְבָאוֹת, מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ: וּמְקַבְּלִין דֵּין מִן דֵּין וְאָמְרִין: קַדִּישׁ בִּשְׁמֵי מֵרוֹמַא עִלָאַה בֵּית שְׁכִינְתֵּהּ, קַדִּישׁ עַל אַרְעָא עוֹבַד גְּבוּרְתֵּהּ, קַדִּישׁ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא, יהוה צְבָאוֹת מַלְיָא כָל אַרְעָא זִיו יְקָרֵהּ. וַתִּשָּׂאֵנִי רוּחַ, וָאֶשְׁמַע אַחֲרַי קוֹל רַעַשׁ גָּדוֹל: בָּרוּךְ כְּבוֹד יהוה מִמְּקוֹמוֹ: וּנְטָלַתְנִי רוּחָא, וּשְׁמָעִית בַּתְרַי קַל זִיעַ שַׂגִּיא דִמְשַׁבְּחִין וְאָמְרִין: בְּרִיךְ יְקָרָא דַיהוה מֵאֲתָר בֵּית שְׁכִינְתֵּהּ. יהוה יִמְלֹךְ לְעוֹלָם וָעֶד: יהוה מַלְכוּתֵיהּ קָאֵים לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\n\nיהוה אֱלֹהֵי אַבְרָהָם יִצְחָק וְיִשְׂרָאֵל אֲבוֹתֵינוּ, שָׁמְרָה זֹּאת לְעוֹלָם, לְיֵצֶר מַחְשְׁבוֹת לְבַב עַמֶּךָ, וְהָכֵן לְבָבָם אֵלֶיךָ: וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית, וְהִרְבָּה לְהָשִׁיב אַפּוֹ, וְלֹא יָעִיר כָּל חֲמָתוֹ: כִּי אַתָּה יהוה טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קוֹרְאֶיךָ: צִדְקָתְךָ צֶּדֶק לְעוֹלָם, וְתוֹרָתְךָ אֱמֶת: תִּתֵּן אֱמֶת לְיַעֲקֹב, חֶסֶד לְאַבְרָהָם, אֲשֶׁר נִשְׁבַּעְתָּ לַאֲבֹתֵינוּ מִימֵי קֶדֶם: בָּרוּךְ אֲדֹנָי יוֹם יוֹם, יַעֲמָס לָנוּ הָאֵל יְשׁוּעָתֵנוּ, סֶלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב, סֶלָה: יהוה צְבָאוֹת אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ: בָּרוּךְ הוּא אֱלֹהֵינוּ שֶׁבְּרָאָנוּ לִכְבוֹדוֹ, וְהִבְדִּילָנוּ מִן הַתּוֹעִים, וְנָתַן לָנוּ תּוֹרַת אֱמֶת, וְחַיֵּי עוֹלָם נָטַע בְּתוֹכֵנוּ. הוּא יִפְתַּח לִבֵּנוּ בְּתוֹרָתוֹ, וְיָשֵׂם בְּלִבֵּנוּ אַהֲבָתוֹ וְיִרְאָתוֹ וְלַעֲשׂוֹת רְצוֹנוֹ וּלְעָבְדוֹ בְּלֵבָב שָׁלֵם. לְמַעַן לֹא נִיגַע לָרִיק, וְלֹא נֵלֵד לַבֶּהָלָה. יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁנִּשְׁמֹר חֻקֶּיךָ בָּעוֹלָם הַזֶּה, וְנִזְכֶּה וְנִחְיֶה וְנִרְאֶה וְנִירַשׁ טוֹבָה וּבְרָכָה לִשְׁנֵי יְמוֹת הַמָּשִׁיחַ וּלְחַיֵּי הָעוֹלָם הַבָּא. לְמַעַן יְזַמֶּרְךָ כָבוֹד וְלֹא יִדֹּם, יהוה אֱלֹהַי לְעוֹלָם אוֹדֶךָּ: בָּרוּךְ הַגֶּבֶר אֲשֶׁר יִבְטַח בַּיהוה, וְהָיָה יהוה מִבְטַחוֹ: בִּטְחוּ בַיהוה עֲדֵי עַד, כִּי בְּיָהּ יהוה צוּר עוֹלָמִים: וְיִבְטְחוּ בְךָ יוֹדְעֵי שְׁמֶךָ, כִּי לֹא עָזַבְתָּ דֹּרְשֶׁיךָ יהוה: יהוה חָפֵץ לְמַעַן צִדְקוֹ, יַגְדִּיל תּורָה וְיַאְדִּיר: יהוה אֲדֹנֵינוּ, מָה אַדִּיר שִׁמְךָ בְּכָל הָאָרֶץ: חִזְקוּ וְיַאֲמֵץ לְבַבְכֶם כָּל הַמְיַחֲלִים לַיהוה:","cond":["tishaaBeav"]},{"kind":"instruction","text":"קדיש שלם (ללא תתקבל)","cond":["megilatEster"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":["megilatEster"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["megilatEster","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["megilatEster","ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":["megilatEster"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["megilatEster","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["megilatEster","ayt"]},{"kind":"instruction","text":"קדיש שלם (ללא תתקבל)","cond":["tishaaBeav"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":["tishaaBeav"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":["tishaaBeav"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav","ayt"]},{"kind":"header","text":"מזמור לפורים","cond":["purim"]},{"kind":"instruction","text":"יש אומרים מזמור זה בפורים, ויש האומרים \"שיר למעלות\" גם בפורים.","cond":["purim"]},{"kind":"text","text":"לַמְנַצֵּחַ עַל אַיֶּלֶת הַשַּׁחַר, מִזְמוֹר לְדָוִד: אֵלִי אֵלִי לָמָה עֲזַבְתָּנִי, רָחוֹק מִישׁוּעָתִי דִּבְרֵי שַׁאֲגָתִי: אֱלֹהַי, אֶקְרָא יוֹמָם וְלֹא תַעֲנֶה, וְלַיְלָה וְלֹא דוּמִיָּה לִי: וְאַתָּה קָדוֹשׁ, יוֹשֵׁב תְּהִלּוֹת יִשְׂרָאֵל: בְּךָ בָּטְחוּ אֲבֹתֵינוּ, בָּטְחוּ וַתְּפַלְּטֵמוֹ: אֵלֶיךָ זָעֲקוּ וְנִמְלָטוּ, בְּךָ בָטְחוּ וְלֹא בוֹשׁוּ: וְאָנֹכִי תוֹלַעַת וְלֹא אִישׁ, חֶרְפַּת אָדָם וּבְזוּי עָם: כָּל רֹאַי יַלְעִגוּ לִי, יַפְטִירוּ בְשָׂפָה יָנִיעוּ רֹאשׁ: גֹּל אֶל יהוה יְפַלְּטֵהוּ, יַצִּילֵהוּ כִּי חָפֵץ בּוֹ: כִּי אַתָּה גֹחִי מִבָּטֶן, מַבְטִיחִי עַל שְׁדֵי אִמִּי: עָלֶיךָ הָשְׁלַכְתִּי מֵרָחֶם, מִבֶּטֶן אִמִּי אֵלִי אָתָּה אַל תִּרְחַק מִמֶּנִּי כִּי צָרָה קְרוֹבָה, כִּי אֵין עוֹזֵר: סְבָבוּנִי פָּרִים רַבִּים, אַבִּירֵי בָשָׁן כִּתְּרוּנִי: פָּצוּ עָלַי פִּיהֶם, אַרְיֵה טֹרֵף וְשֹׁאֵג: כַּמַּיִם נִשְׁפַּכְתִּי וְהִתְפָּרְדוּ כָּל עַצְמוֹתָי, הָיָה לִבִּי כַּדּוֹנָג, נָמֵס בְּתוֹךְ מֵעָי: יָבֵשׁ כַּחֶרֶשׂ כֹּחִי וּלְשׁוֹנִי מֻדְבָּק מַלְקוֹחָי, וְלַעֲפַר מָוֶת תִּשְׁפְּתֵנִי: כִּי סְבָבוּנִי כְּלָבִים, עֲדַת מְרֵעִים הִקִּיפוּנִי, כָּאֲרִי יָדַי וְרַגְלָי: אֲסַפֵּר כָּל עַצְמוֹתָי, הֵמָּה יַבִּיטוּ יִרְאוּ בִי: יְחַלְּקוּ בְגָדַי לָהֶם, וְעַל לְבוּשִׁי יַפִּילוּ גוֹרָל: וְאַתָּה יהוה אַל תִּרְחָק, אֱיָלוּתִי לְעֶזְרָתִי חוּשָׁה: הַצִּילָה מֵחֶרֶב נַפְשִׁי, מִיַּד כֶּלֶב יְחִידָתִי: הוֹשִׁיעֵנִי מִפִּי אַרְיֵה, וּמִקַּרְנֵי רֵמִים עֲנִיתָנִי: אֲסַפְּרָה שִׁמְךָ לְאֶחָי, בְּתוֹךְ קָהָל אֲהַלְלֶךָּ: יִרְאֵי יהוה הַלְלוּהוּ, כָּל זֶרַע יַעֲקֹב כַּבְּדוּהוּ, וְגוּרוּ מִמֶּנּוּ כָּל זֶרַע יִשְׂרָאֵל: כִּי לֹא בָזָה וְלֹא שִׁקַּץ עֱנוּת עָנִי, וְלֹא הִסְתִּיר פָּנָיו מִמֶּנּוּ, וּבְשַׁוְּעוֹ אֵלָיו שָׁמֵעַ: מֵאִתְּךָ תְהִלָּתִי בְּקָהָל רָב, נְדָרַי אֲשַׁלֵּם נֶגֶד יְרֵאָיו: יֹאכְלוּ עֲנָוִים וְיִשְׂבָּעוּ, יְהַלְלוּ יהוה דֹּרְשָׁיו, יְחִי לְבַבְכֶם לָעַד: יִזְכְּרוּ וְיָשֻׁבוּ אֶל יהוה כָּל אַפְסֵי אָרֶץ, וְיִשְׁתַּחֲווּ לְפָנֶיךָ כָּל מִשְׁפְּחוֹת גּוֹיִם: כִּי לַיהוה הַמְּלוּכָה, וּמֹשֵׁל בַּגּוֹיִם: אָכְלוּ וַיִּשְׁתַּחֲוּוּ כָּל דִּשְׁנֵי אֶרֶץ, לְפָנָיו יִכְרְעוּ כָּל יוֹרְדֵי עָפָר, וְנַפְשׁוֹ לֹא חִיָּה: זֶרַע יַעַבְדֶנּוּ, יְסֻפַּר לַאדֹנָי לַדּוֹר: יָבֹאוּ וְיַגִּידוּ צִדְקָתוֹ, לְעַם נוֹלָד כִּי עָשָׂה:","cond":["purim"]},{"kind":"header","text":"מזמור לסוכות","cond":["sucot"]},{"kind":"instruction","text":"יש אומרים מזמור זה בסוכות, ויש האומרים \"שיר למעלות אשא עיני\" גם בסוכות.","cond":["sucot"]},{"kind":"text","text":"שִׁיר הַמַּעֲלוֹת לְדָוִד: שָׂמַחְתִּי בְּאֹמְרִים לִי בֵּית יהוה נֵלֵךְ: עֹמְדוֹת הָיוּ רַגְלֵינוּ, בִּשְׁעָרַיִךְ יְרוּשָׁלָיִם: יְרוּשָׁלַיִם הַבְּנוּיָה, כְּעִיר שֶׁחֻבְּרָה-לָּהּ יַחְדָּו: שֶׁשָּׁם עָלוּ שְׁבָטִים שִׁבְטֵי-יָהּ, עֵדוּת לְיִשְׂרָאֵל, לְהֹדוֹת לְשֵׁם יהוה: כִּי שָׁמָּה יָשְׁבוּ כִסְאוֹת לְמִשְׁפָּט, כִּסְאוֹת לְבֵית דָּוִד: שַׁאֲלוּ שְׁלוֹם יְרוּשָׁלָיִם, יִשְׁלָיוּ אֹהֲבָיִךְ: יְהִי-שָׁלוֹם בְּחֵילֵךְ, שַׁלְוָה בְּאַרְמְנוֹתָיִךְ: לְמַעַן אַחַי וְרֵעָי, אֲדַבְּרָה-נָּא שָׁלוֹם בָּךְ: לְמַעַן בֵּית-יהוה אֱלֹהֵינוּ, אֲבַקְשָׁה טוֹב לָךְ:","cond":["sucot"]},{"kind":"header","text":"מזמור לפסח","cond":["pesach"]},{"kind":"instruction","text":"יש אומרים מזמור זה בפסח, ויש האומרים \"שיר למעלות\" גם בפסח.","cond":["pesach"]},{"kind":"text","text":"בְּצֵאת יִשְׂרָאֵל מִמִּצְרָיִם, בֵּית יַעֲקֹב מֵעַם לֹעֵז: הָיְתָה יְהוּדָה לְקָדְשׁוֹ, יִשְׂרָאֵל מַמְשְׁלוֹתָיו: הַיָּם רָאָה וַיָּנֹס, הַיַּרְדֵּן יִסֹּב לְאָחוֹר: הֶהָרִים רָקְדוּ כְאֵילִים, גְּבָעוֹת כִּבְנֵי צֹאן: מַה לְּךָ הַיָּם כִּי תָנוּס, הַיַּרְדֵּן תִּסֹּב לְאָחוֹר: הֶהָרִים תִּרְקְדוּ כְאֵילִים, גְּבָעוֹת כִּבְנֵי צֹאן: מִלִּפְנֵי אָדוֹן חוּלִי אָרֶץ, מִלִּפְנֵי אֱלוֹהַּ יַעֲקֹב: הַהֹפְכִי הַצּוּר אֲגַם מָיִם, חַלָּמִישׁ לְמַעְיְנוֹ מָיִם:","cond":["pesach"]},{"kind":"header","text":"מזמור לחנוכה","cond":["chanuka"]},{"kind":"instruction","text":"יש אומרים מזמור זה בחנוכה, ויש האומרים \"שיר למעלות\" גם בחנוכה.","cond":["chanuka"]},{"kind":"text","text":"מִזְמוֹר שִׁיר חֲנֻכַּת הַבַּיִת לְדָוִד: אֲרוֹמִמְךָ יהוה כִּי דִלִּיתָנִי, וְלֹא שִׂמַּחְתָּ אֹיְבַי לִי: יהוה אֱלֹהָי שִׁוַּעְתִּי אֵלֶיךָ וַתִּרְפָּאֵנִי: יהוה, הֶעֱלִיתָ מִן שְׁאוֹל נַפְשִׁי, חִיִּיתַנִי מִיָּרְדִי בוֹר: זַמְּרוּ לַיהוה חֲסִידָיו וְהוֹדוּ לְזֵכֶר קָדְשׁוֹ: כִּי רֶגַע בְּאַפּוֹ חַיִּים בִּרְצוֹנוֹ, בָּעֶרֶב יָלִין בֶּכִי וְלַבֹּקֶר רִנָּה: וַאֲנִי אָמַרְתִּי בְשַׁלְוִי בַּל אֶמּוֹט לְעוֹלָם: יהוה בִּרְצוֹנְךָ הֶעֱמַדְתָּה לְהַרְרִי עֹז, הִסְתַּרְתָּ פָנֶיךָ הָיִיתִי נִבְהָל: אֵלֶיךָ יהוה אֶקְרָא וְאֶל אֲדֹנָי אֶתְחַנָּן: מַה בֶּצַע בְּדָמִי בְּרִדְתִּי אֶל שָׁחַת, הֲיוֹדְךָ עָפָר הֲיַגִּיד אֲמִתֶּךָ: שְׁמַע יהוה וְחָנֵּנִי, יהוה הֱיֵה עֹזֵר לִי: הָפַכְתָּ מִסְפְּדִי לְמָחוֹל לִי, פִּתַּחְתָּ שַׂקִּי וַתְּאַזְּרֵנִי שִׂמְחָה: לְמַעַן יְזַמֶּרְךָ כָבוֹד וְלֹא יִדֹּם, יהוה אֱלֹהַי לְעוֹלָם אוֹדֶךָּ:","cond":["chanuka"]},{"kind":"header","text":"שיר למעלות","cond":[]},{"kind":"text","text":"שִׁיר לַמַּעֲלוֹת, אֶשָּׂא עֵינַי אֶל הֶהָרִים, מֵאַיִן יָבֹא עֶזְרִי: עֶזְרִי מֵעִם יהוה, עֹשֵׂה שָׁמַיִם וָאָרֶץ: אַל יִתֵּן לַמּוֹט רַגְלֶךָ, אַל יָנוּם שֹׁמְרֶךָ: הִנֵּה לֹא יָנוּם וְלֹא יִישָׁן שׁוֹמֵר יִשְׂרָאֵל: יהוה שֹׁמְרֶךָ, יהוה צִלְּךָ עַל יַד יְמִינֶךָ: יוֹמָם הַשֶּׁמֶשׁ לֹא יַכֶּכָּה, וְיָרֵחַ בַּלָּיְלָה: יהוה יִשְׁמָרְךָ מִכָּל רָע, יִשְׁמֹר אֶת נַפְשֶׁךָ: יהוה יִשְׁמָר צֵאתְךָ וּבוֹאֶךָ, מֵעַתָּה וְעַד עוֹלָם:","cond":[]},{"kind":"instruction","text":"קדיש יתום","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":[]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"instruction","text":"חזן:","cond":[]},{"kind":"text","text":"בָּרְכוּ אֶת יהוה הַמְבֹרָךְ.","cond":[]},{"kind":"instruction","text":"קהל וחזן:","cond":[]},{"kind":"text","text":"בָּרוּךְ יהוה הַמְבֹרָךְ לְעוֹלָם וָעֶד.","cond":[]},{"kind":"header","text":"ספירת העומר","cond":["omer"]},{"kind":"instruction","text":"ספירת העומר","cond":["omer"]},{"kind":"text","text":"לְשֵׁם יִחוּד קֻדְשָׁא בְּרִיךְ הוּא וּשְׁכִינְתֵּיהּ בִּדְחִילוּ וּרְחִימוּ, לְיַחֵד שֵׁם י\"ה בְּו\"ה בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל יִשְׂרָאֵל, הִנְנִי מוּכָן וּמְזֻמָּן לְקַיֵּם מִצְוַת עֲשֵׂה שֶׁל סְפִירַת הָעֹמֶר, כְּמו שֶׁכָּתוּב בַּתּוֹרָה: וּסְפַרְתֶּם לָכֶם מִמָּחֳרַת הַשַּׁבָּת, מִיוֹם הֲבִיאֲכֶם אֶת עֹמֶר הַתְּנוּפָה, שֶׁבַע שַׁבָּתוֹת תְּמִימוֹת תִּהְיֶינָה: עַד מִמָּחֳרַת הַשַּׁבָּת הַשְּׁבִיעִית תִּסְפְּרוּ חֲמִשִּׁים יוֹם, וְהִקְרַבְתֶּם מִנְחָה חֲדָשָׁה לַיהוה: וִיהִי נֹעַם יהוה אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ:\n\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ עַל סְפִירַת הָעֹמֶר.\n\n::::::\n\nהָרַחֲמָן הוּא יַחֲזִיר לָנוּ עֲבוֹדַת בֵּית הַמִּקְדָּשׁ לִמְקוֹמָהּ בִּמְהֵרָה בְיָמֵינוּ. אָמֵן סֶלָה.","cond":["omer"]},{"kind":"text","text":"לַמְנַצֵּחַ בִּנְגִינֹת מִזְמוֹר שִׁיר: אֱלֹהִים יְחָנֵּנוּ וִיבָרְכֵנוּ, יָאֵר פָּנָיו אִתָּנוּ סֶלָה: לָדַעַת בָּאָרֶץ דַּרְכֶּךָ, בְּכָל-גּוֹיִם יְשׁוּעָתֶךָ: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: יִשְׂמְחוּ וִירַנְּנוּ לְאֻמִּים כִּי-תִשְׁפֹּט עַמִּים מִישֹׁר, וּלְאֻמִּים בָּאָרֶץ תַּנְחֵם סֶלָה: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: אֶרֶץ נָתְנָה יְבוּלָהּ, יְבָרְכֵנוּ אֱלֹהִים אֱלֹהֵינוּ: יְבָרְכֵנוּ אֱלֹהִים, וְיִירְאוּ אוֹתוֹ כָּל-אַפְסֵי-אָרֶץ:","cond":["omer"]},{"kind":"text","text":"אָנָּא, בְּכֹחַ גְּדֻלַּת יְמִינְךָ, תַּתִּיר צְרוּרָה (אב\"ג ית\"ץ).","cond":["omer"]},{"kind":"text","text":"קַבֵּל רִנַּת עַמְּךָ, שַׂגְּבֵנוּ, טַהֲרֵנוּ, נוֹרָא (קר\"ע שט\"ן).","cond":["omer"]},{"kind":"text","text":"נָא גִּבּוֹר, דּוֹרְשֵׁי יִחוּדֶךָ, כְּבָבַת שָׁמְרֵם (נג\"ד יכ\"ש).","cond":["omer"]},{"kind":"text","text":"בָּרְכֵם, טַהֲרֵם, רַחֲמֵי צִדְקָתְךָ תָּמִיד גָּמְלֵם (בט\"ר צת\"ג).","cond":["omer"]},{"kind":"text","text":"חָסִין קָדוֹשׁ, בְּרֹב טוּבְךָ נַהֵל עֲדָתֶךָ (חק\"ב טנ\"ע).","cond":["omer"]},{"kind":"text","text":"יָחִיד גֵּאֶה, לְעַמְּךָ פְנֵה, זוֹכְרֵי קְדֻשָּׁתֶךָ (יג\"ל פז\"ק).","cond":["omer"]},{"kind":"text","text":"שַׁוְעָתֵנוּ קַבֵּל, וּשְׁמַע צַעֲקָתֵנוּ, יוֹדֵעַ תַּעֲלוּמוֹת (שק\"ו צי\"ת).","cond":["omer"]},{"kind":"text","text":"בלחש - בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֵד.\n\nרִבּוֹנוֹ שֶׁל עוֹלָם, אַתָּה צִוִּיתָנוּ עַל יְדֵי מֹשֶׁה עַבְדְּךָ לִסְפֹּר סְפִירַת הָעֹמֶר כְּדֵי לְטַהֲרֵנוּ מִקְּלִפּוֹתֵינוּ וּמִטֻּמְאוֹתֵינוּ, כְּמוֹ שֶׁכָּתַבְתָּ בְּתוֹרָתֶךָ: וּסְפַרְתֶּם לָכֶם מִמָּחֳרַת הַשַּׁבָּת, מִיוֹם הֲבִיאֲכֶם אֶת עֹמֶר הַתְּנוּפָה, שֶׁבַע שַׁבָּתוֹת תְּמִימוֹת תִּהְיֶינָה: עַד מִמָּחֳרַת הַשַּׁבָּת הַשְּׁבִיעִית תִּסְפְּרוּ חֲמִשִּׁים יוֹם, כְּדֵי שֶׁיִּטָּהֲרוּ נַפְשׁוֹת עַמְּךָ יִשְׂרָאֵל מִזֻּהֲמָתָם. וּבְכֵן יְהִי רָצוֹן מִלְּפָנֶיךָ, יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁבִּזְכוּת סְפִירַת הָעֹמֶר שֶׁסָּפַרְתִּי הַיּוֹם, יְתֻקַּן מַה שֶׁפָּגַמְתִּי בִּסְפִירָה\n:::\nוְאֶטָּהֵר וְאֶתְקַדֵּשׁ בִּקְדֻשָּׁה שֶׁל מַעְלָה, וְעַל יְדֵי זֶה יֻשְׁפַּע שֶׁפַע רַב בְּכָל הָעוֹלָמוֹת לְתַקֵּן אֶת נַפְשׁוֹתֵינוּ וְרוּחוֹתֵינוּ וְנִשְׁמוֹתֵינוּ מִכָּל סִיג וּפְגַם, וּלְטַהֲרֵנוּ וּלְקַדְּשֵׁנוּ בִּקְדֻשָּׁתְךָ הָעֶלְיוֹנָה, אָמֵן סֶלָה.","cond":["omer"]},{"kind":"header","text":"עלינו לשבח","cond":[]},{"kind":"text","text":"עָלֵינוּ לְשַׁבֵּחַ לַאֲדוֹן הַכֹּל, לָתֵת גְּדֻלָּה לְיוֹצֵר בְּרֵאשִׁית, שֶׁלֹּא עָשָׂנוּ כְּגוֹיֵי הָאֲרָצוֹת, וְלֹא שָׂמָנוּ כְּמִשְׁפְּחוֹת הָאֲדָמָה. שֶׁלֹּא שָׂם חֶלְקֵנוּ כָּהֶם, וְגוֹרָלֵנוּ כְּכָל-הֲמוֹנָם[, שֶׁהֵם מִשְׁתַּחֲוִים לְהֶבֶל וָרִיק, וּמִתְפַּלְּלִים אֶל אֵל לֹא יוֹשִׁיעַ]. וַאֲנַחְנוּ כּוֹרְעִים וּמִשְׁתַּחֲוִים וּמוֹדִים לִפְנֵי מֶלֶךְ מַלְכֵי הַמְּלָכִים הַקָּדוֹשׁ בָּרוּךְ הוּא, שֶׁהוּא נוֹטֶה שָׁמַיִם וְיוֹסֵד אָרֶץ, וּמוֹשַׁב יְקָרוֹ בַּשָּׁמַיִם מִמַּעַל, וּשְׁכִינַת עֻזּוֹ בְּגָבְהֵי מְרוֹמִים. הוּא אֱלֹהֵינוּ, אֵין עוֹד, אֱמֶת מַלְכֵּנוּ, אֶפֶס זוּלָתוֹ. כַּכָּתוּב בְּתוֹרָתוֹ: וְיָדַעְתָּ הַיּוֹם וַהֲשֵׁבֹתָ אֶל לְבָבֶךָ כִּי יהוה הוּא הָאֱלֹהִים בַּשָּׁמַיִם מִמַּעַל וְעַל הָאָרֶץ מִתָּחַת אֵין עוֹד:","cond":[]},{"kind":"text","text":"וְעַל כֵּן נְקַוֶּה לְךָ יהוה אֱלֹהֵינוּ, לִרְאוֹת מְהֵרָה בְּתִפְאֶרֶת עֻזֶּךָ, לְהַעֲבִיר גִּלּוּלִים מִן הָאָרֶץ, וְהָאֱלִילִים כָּרוֹת יִכָּרֵתוּן, לְתַקֵּן עוֹלָם בְּמַלְכוּת שַׁדַּי, וְכָל בְּנֵי בָשָׂר יִקְרְאוּ בִשְׁמֶךָ, לְהַפְנוֹת אֵלֶיךָ כָּל רִשְׁעֵי אָרֶץ. יַכִּירוּ וְיֵדְעוּ כָּל יוֹשְׁבֵי תֵבֵל, כִּי לְךָ תִכְרַע כָּל בֶּרֶךְ, תִּשָּׁבַע כָּל לָשׁוֹן. לְפָנֶיךָ יהוה אֱלֹהֵינוּ יִכְרְעוּ וְיִפֹּלוּ, וְלִכְבוֹד שִׁמְךָ יְקָר יִתֵּנוּ, וִיקַבְּלוּ כֻלָּם אֶת עֹל מַלְכוּתֶךָ, וְתִמְלֹךְ עֲלֵיהֶם מְהֵרָה לְעוֹלָם וָעֶד. כִּי הַמַּלְכוּת שֶׁלְּךָ הִיא, וּלְעוֹלְמֵי עַד תִּמְלֹךְ בְּכָבוֹד. כַּכָּתוּב בְּתוֹרָתֶךָ: יהוה יִמְלֹךְ לְעֹלָם וָעֶד: וְנֶאֱמַר: וְהָיָה יהוה לְמֶלֶךְ עַל כָּל הָאָרֶץ, בַּיּוֹם הַהוּא יִהְיֶה יהוה אֶחָד וּשְׁמוֹ אֶחָד:","cond":[]},{"kind":"text","text":"אַל תִּירָא מִפַּחַד פִּתְאֹם וּמִשֹּׁאַת רְשָׁעִים כִּי תָבֹא: עֻצוּ עֵצָה וְתֻפָר, דַּבְּרוּ דָבָר וְלֹא יָקוּם, כִּי עִמָּנוּ אֵל: וְעַד זִקְנָה אֲנִי הוּא, וְעַד שֵׂיבָה אֲנִי אֶסְבֹּל אֲנִי עָשִׂיתִי וַאֲנִי אֶשָּׂא וַאֲנִי אֶסְבֹּל וַאֲמַלֵּט:","cond":[]},{"kind":"instruction","text":"קדיש יתום","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":[]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"header","text":"אני מאמין","cond":["yerushalayim"]},{"kind":"instruction","text":"שרים:","cond":["yerushalayim"]},{"kind":"text","text":"אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה בְּבִיאַת הַמָּשִׁיחַ, וְאַף עַל פִּי שֶׁיִּתְמַהְמֵהַּ, עִם כָּל זֶה אֲחַכֶּה לוֹ בְּכָל יוֹם שֶׁיָּבוֹא.","cond":["yerushalayim"]},{"kind":"header","text":"לדוד","cond":["ledavid"]},{"kind":"special","text":"לְדָוִד, יהוה אוֹרִי וְיִשְׁעִי מִמִּי אִירָא, יהוה מָעוֹז חַיַּי מִמִּי אֶפְחָד: בִּקְרֹב עָלַי מְרֵעִים לֶאֱכֹל אֶת בְּשָׂרִי, צָרַי וְאֹיְבַי לִי, הֵמָּה כָשְׁלוּ וְנָפָלוּ: אִם תַּחֲנֶה עָלַי מַחֲנֶה לֹא יִירָא לִבִּי, אִם תָּקוּם עָלַי מִלְחָמָה בְּזֹאת אֲנִי בוֹטֵחַ: אַחַת שָׁאַלְתִּי מֵאֵת יהוה, אוֹתָהּ אֲבַקֵּשׁ, שִׁבְתִּי בְּבֵית יהוה כָּל יְמֵי חַיַּי, לַחֲזוֹת בְּנֹעַם יהוה וּלְבַקֵּר בְּהֵיכָלוֹ: כִּי יִצְפְּנֵנִי בְּסֻכֹּה בְּיוֹם רָעָה יַסְתִּירֵנִי בְּסֵתֶר אָהֳלוֹ, בְּצוּר יְרוֹמְמֵנִי: וְעַתָּה יָרוּם רֹאשִׁי עַל אֹיְבַי סְבִיבוֹתַי, וְאֶזְבְּחָה בְאָהֳלוֹ זִבְחֵי תְרוּעָה, אָשִׁירָה וַאֲזַמְּרָה לַיהוה: שְׁמַע יהוה קוֹלִי אֶקְרָא, וְחָנֵּנִי וַעֲנֵנִי: לְךָ אָמַר לִבִּי בַּקְּשׁוּ פָנַי, אֶת פָּנֶיךָ יהוה אֲבַקֵּשׁ: אַל תַּסְתֵּר פָּנֶיךָ מִמֶּנִּי, אַל תַּט בְּאַף עַבְדֶּךָ, עֶזְרָתִי הָיִיתָ, אַל תִּטְּשֵׁנִי וְאַל תַּעַזְבֵנִי אֱלֹהֵי יִשְׁעִי: כִּי אָבִי וְאִמִּי עֲזָבוּנִי, וַיהוה יַאַסְפֵנִי: הוֹרֵנִי יהוה דַּרְכֶּךָ וּנְחֵנִי בְּאֹרַח מִישׁוֹר לְמַעַן שׁוֹרְרָי: אַל תִּתְּנֵנִי בְּנֶפֶשׁ צָרָי, כִּי קָמוּ בִי עֵדֵי שֶׁקֶר וִיפֵחַ חָמָס: לוּלֵא הֶאֱמַנְתִּי לִרְאוֹת בְּטוּב יהוה בְּאֶרֶץ חַיִּים: קַוֵּה אֶל יהוה, חֲזַק וְיַאֲמֵץ לִבֶּךָ, וְקַוֵּה אֶל יהוה:","cond":["ledavid"]},{"kind":"instruction","text":"קדיש יתום","cond":["ledavid"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":["ledavid"]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ledavid","noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ledavid","ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":["ledavid"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ledavid","noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ledavid","ayt"]},{"kind":"header","text":"הבדלה","cond":["havdala"]},{"kind":"instruction","text":"סדר הבדלה\n\nנוטל הכוס בידו ואומר:","cond":["havdala"]},{"kind":"text","text":"הִנֵּה אֵל יְשׁוּעָתִי אֶבְטַח וְלֹא אֶפְחָד: כִּי עָזִּי וְזִמְרָת יָהּ יהוה, וַיְהִי לִי לִישׁוּעָה: וּשְׁאַבְתֶּם מַיִם בְּשָׂשׂוֹן, מִמַּעַיְנֵי הַיְשׁוּעָה: לַיהוה הַיְשׁוּעָה, עַל עַמְּךָ בִרְכָתֶךָ סֶּלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה: יהוה צְבָאוֹת, אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ: לַיְּהוּדִים הָיְתָה אוֹרָה וְשִׂמְחָה, וְשָׂשׁוֹן וִיקָר: כֵּן תִּהְיֶה לָנוּ. כּוֹס יְשׁוּעוֹת אֶשָּׂא, וּבְשֵׁם יהוה אֶקְרָא:","cond":["havdala","sun"]},{"kind":"text","text":"סַבְרִי מָרָנָן וְרַבָּנָן וְרַבּוֹתַי.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא פְּרִי הַגָּפֶן.","cond":["havdala"]},{"kind":"instruction","text":"ואם מברך על משקה שאינו יין יברך שהכל.","cond":["havdala"]},{"kind":"instruction","text":"מוריד את הכוס ונוטל את הבשמים ומברך:","cond":["havdala","sun"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא (עֲצֵי או עִשְׂבֵּי או מִינֵי) בְשָׂמִים.","cond":["havdala","sun"]},{"kind":"instruction","text":"מברך לאור הנר:","cond":["havdala","fire"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא מְאוֹרֵי הָאֵשׁ.","cond":["havdala","fire"]},{"kind":"instruction","text":"נוטל את הכוס בידו ומברך:","cond":["havdala"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַמַּבְדִּיל בֵּין קֹדֶשׁ לְחוֹל, בֵּין אוֹר לְחֹשֶׁךְ, בֵּין יִשְׂרָאֵל לָעַמִּים, בֵּין יוֹם הַשְּׁבִיעִי לְשֵׁשֶׁת יְמֵי הַמַּעֲשֶׂה. בָּרוּךְ אַתָּה יהוה, הַמַבְדִּיל בֵּין קֹדֶשׁ לְחוֹל.","cond":["havdala"]},{"kind":"instruction","text":"אם שתה רביעית יין יברך ברכת מעין שלש (מופיע בתפריט התפילות).","cond":["havdala"]},{"kind":"header","text":"ויתן לך","cond":["sun"]},{"kind":"instruction","text":"פסוקים הנהוגים לומר במוצאי שבת לסימן ברכה:","cond":["sun"]},{"kind":"text","text":"וְיִתֶּן לְךָ הָאֱלהִים מִטַּל הַשָּׁמַיִם וּמִשְׁמַנֵּי הָאָרֶץ, וְרֹב דָגָן וְתִירֹשׁ: יַעַבְדּוּךָ עַמִּים וְיִשְׁתַּחֲווּ לְךָ לְאֻמִּים, הֱוֵה גְבִיר לְאַחֶיךָ וְיִשְׁתַּחֲווּ לְךָ בְּנֵי אִמֶּךָ, אֹרְרֶיךָ אָרוּר וּמְבָרְכֶיךָ בָּרוּךְ:\n\nוְאֵל שַׁדַּי יְבָרֵךְ אֹתְךָ וְיַפְרְךָ וְיַרְבֶּךָ, וְהָיִיתָ לִקְהַל עַמִּים: וְיִתֵּן לְךָ אֶת בִּרְכַּת אַבְרָהָם לְךָ וּלְזַרְעֲךָ אִתָּךְ, לְרִשְׁתְּךָ אֶת אֶרֶץ מְגֻרֶיךָ, אֲשֶׁר נָתַן אֱלֹהִים לְאַבְרָהָם: מֵאֵל אָבִיךָ וְיַעְזְרֶךָּ, וְאֵת שַׁדַּי וִיבָרְכֶךָּ, בִּרְכֹת שָׁמַיִם מֵעָל, בִּרְכֹת תְּהוֹם רֹבֶצֶת תָּחַת, בִּרְכֹת שָׁדַיִם וָרָחַם: בִּרְכֹת אָבִיךָ גָּבְרוּ עַל בִּרְכֹת הוֹרַי עַד תַּאֲוַת גִּבְעֹת עוֹלָם, תִּהְיֶיןָ לְרֹאשׁ יוסֵף וּלְקָדְקֹד נְזִיר אֶחָיו: וַאֲהֵבְךָ וּבֵרַכְךָ וְהִרְבֶּךָ, וּבֵרַךְ פְּרִי בִטְנְךָ וּפְרִי אַדְמָתֶךָ, דְּגָנְךָ וְתִירֹשְׁךָ וְיִצְהָרֶךָ, שְׁגַר אֲלָפֶיךָ וְעַשְׁתְּרֹת צֹאנֶךָ, עַל הָאֲדָמָה אֲשֶׁר נִשְׁבַּע לַאֲבֹתֶיךָ לָתֶת לָךְ: בָּרוּךְ תִּהְיֶה מִכָּל הָעַמִּים, לֹא יִהְיֶה בְךָ עָקָר וַעֲקָרָה וּבִבְהֶמְתֶּךָ: וְהֵסִיר יהוה מִמְּךָ כָּל חֹלִי, וְכָל מַדְוֵי מִצְרַיִם הָרָעִים אֲשֶׁר יָדַעְתָּ לֹא יְשִׂימָם בָּךְ, וּנְתָנָם בְּכָל שֹׂנְאֶיךָ:\n\nהַמַּלְאָךְ הַגֹּאֵל אֹתִי מִכָּל רָע יְבָרֵךְ אֶת הַנְּעָרִים, וְיִקָּרֵא בָהֶם שְׁמִי, וְשֵׁם אֲבֹתַי אַבְרָהָם וְיִצְחָק, וְיִדְגּוּ לָרֹב בְּקֶרֶב הָאָרֶץ: יהוה אֱלֹהֵיכֶם הִרְבָּה אֶתְכֶם, וְהִנְּכֶם הַיּוֹם כְּכוֹכְבֵי הַשָּׁמַיִם לָרֹב: יהוה אֱלֹהֵי אֲבוֹתֵכֶם יֹסֵף עֲלֵיכֶם כָּכֶם אֶלֶף פְּעָמִים, וִיבָרֵךְ אֶתְכֶם כַּאֲשֶׁר דִּבֶּר לָכֶם:\n\nבָּרוּךְ אַתָּה בָּעִיר, וּבָרוּךְ אַתָּה בַּשָּׂדֶה: בָּרוּךְ אַתָּה בְּבֹאֶךָ, וּבָרוּךְ אַתָּה בְּצֵאתֶךָ: בָּרוּךְ טַנְאֲךָ וּמִשְׁאַרְתֶּךָ: בָּרוּךְ פְּרִי בִטְנְךָ וּפְרִי אַדְמָתְךָ וּפְרִי בְהֶמְתֶּךָ, שְׁגַר אֲלָפֶיךָ וְעַשְׁתְּרוֹת צֹאנֶךָ: יְצַו יהוה אִתְּךָ אֶת הַבְּרָכָה, בַּאֲסָמֶיךָ וּבְכֹל מִשְׁלַח יָדֶךָ, וּבֵרַכְךָ בָּאָרֶץ אֲשֶׁר יהוה אֱלהֶיךָ נֹתֵן לָךְ: יִפְתַּח יהוה לְךָ אֶת אוֹצָרוֹ הַטּוֹב אֶת הַשָּׁמַיִם לָתֵת מְטַר אַרְצְךָ בְּעִתּוֹ וּלְבָרֵךְ אֵת כָּל מַעֲשֵׂה יָדֶךָ, וְהִלְוִיתָ גּוֹיִם רַבִּים וְאַתָּה לֹא תִלְוֶה: כִּי יהוה אֱלֹהֶיךָ בֵּרַכְךָ כַּאֲשֶׁר דִּבֶּר לָךְ, וְהַעֲבַטְתָּ גּוֹיִם רַבִּים וְאַתָּה לֹא תַעֲבֹט, וּמָשַׁלְתָּ בְּגוֹיִם רַבִּים וּבְךָ לֹא יִמְשֹׁלוּ: אַשְׁרֶיךָ יִשְׂרָאֵל, מִי כָמוֹךָ, עַם נושַׁע בַּיהוה, מָגֵן עֶזְרֶךָ, וַאֲשֶׁר חֶרֶב גַּאֲוָתֶךָ, וְיִכָּחֲשׁוּ אוֹיְבֶיךָ לָךְ, וְאַתָּה עַל בָּמוֹתֵימוֹ תִדְרֹךְ:\n\nמָחִיתִי כָעָב פְּשָׁעֶיךָ וְכֶעָנָן חַטֹּאותֶיךָ, שׁוּבָה אֵלַי כִּי גְאַלְתִּיךָ: רָנּוּ שָׁמַיִם כִּי עָשָׂה יהוה, הָרִיעוּ תַּחְתִּיּוֹת אָרֶץ, פִּצְחוּ הָרִים רִנָּה, יַעַר וְכָל עֵץ בּוֹ, כִּי גָאַל יהוה יַעֲקֹב וּבְיִשְׂרָאֵל יִתְפָּאָר: גֹּאֲלֵנוּ יהוה צְבָאוֹת שְׁמוֹ, קְדוֹשׁ יִשְׂרָאֵל:\n\nיִשְׂרָאֵל נוֹשַׁע בַּיהוה תְּשׁוּעַת עוֹלָמִים, לֹא תֵבשׁוּ וְלֹא תִכָּלְמוּ עַד עוֹלְמֵי עַד: וַאֲכַלְתֶּם אָכוֹל וְשָׂבוֹעַ, וְהִלַּלְתֶּם אֶת שֵׁם יהוה אֱלֹהֵיכֶם אֲשֶׁר עָשָׂה עִמָּכֶם לְהַפְלִיא, וְלֹא יֵבֹשׁוּ עַמִּי לְעוֹלָם: וִידַעְתֶּם כִּי בְקֶרֶב יִשְׂרָאֵל אָנִי, וַאֲנִי יהוה אֱלֹהֵיכֶם וְאֵין עוֹד, וְלֹא יֵבשׁוּ עַמִּי לְעוֹלָם: כִּי בְשִׂמְחָה תֵצֵאוּ וּבְשָׁלוֹם תּוּבָלוּן, הֶהָרִים וְהַגְּבָעוֹת יִפְצְחוּ לִפְנֵיכֶם רִנָּה, וְכָל עֲצֵי הַשָּׂדֶה יִמְחֲאוּ כָף: הִנֵּה אֵל יְשׁוּעָתִי אֶבְטַח, וְלֹא אֶפְחָד, כִּי עָזִּי וְזִמְרָת יָהּ יהוה, וַיְהִי לִי לִישׁוּעָה: וּשְׁאַבְתֶּם מַיִם בְּשָׂשׂוֹן מִמַּעַיְנֵי הַיְשׁוּעָה: וַאֲמַרְתֶּם בַּיּוֹם הַהוּא, הוֹדוּ לַיהוה קִרְאוּ בִשְׁמוֹ, הוֹדִיעוּ בָעַמִּים עֲלִילֹתָיו, הַזְכִּירוּ כִּי נִשְׂגָּב שְׁמוֹ: זַמְּרוּ יהוה כִּי גֵאוּת עָשָׂה, מוּדַעַת זֹאת בְּכָל הָאָרֶץ: צַהֲלִי וָרֹנִּי יוֹשֶׁבֶת צִיּוֹן, כִּי גָדוֹל בְּקִרְבֵּךְ קְדוֹשׁ יִשְׂרָאֵל: וְאָמַר בַּיּוֹם הַהוּא, הִנֵּה אֱלֹהֵינוּ זֶה קִוִּינוּ לוֹ, וְיוֹשִׁיעֵנוּ, זֶה יהוה קִוִּינוּ לוֹ, נָגִילָה וְנִשְׂמְחָה בִּישׁוּעָתוֹ: בֵּית יַעֲקֹב, לְכוּ וְנֵלְכָה בְּאוֹר יהוה: וְהָיָה אֱמוּנַת עִתֶּיךָ, חֹסֶן יְשׁוּעֹת, חָכְמַת וָדָעַת, יִרְאַת יהוה הִיא אוֹצָרוֹ: וַיְהִי דָוִד לְכָל דְּרָכָיו מַשְׂכִּיל, וַיהוה עִמּוֹ:\n\nפָּדָה בְשָׁלוֹם נַפְשִׁי מִקְּרָב לִי, כִּי בְרַבִּים הָיוּ עִמָּדִי: וַיֹּאמֶר הָעָם אֶל שָׁאוּל, הֲיוֹנָתָן יָמוּת, אֲשֶׁר עָשָׂה הַיְשׁוּעָה הַגְּדוֹלָה הַזֹּאת בְּיִשְׂרָאֵל, חָלִילָה, חַי יהוה אִם יִפֹּל מִשַּׂעֲרַת רֹאשׁוֹ אַרְצָה, כִּי עִם אֱלֹהִים עָשָׂה הַיּוֹם הַזֶּה, וַיִּפְדּוּ הָעָם אֶת יוֹנָתָן וְלֹא מֵת: וּפְדוּיֵי יהוה יְשֻׁבוּן וּבָאוּ צִיּוֹן בְּרִנָּה וְשִׂמְחַת עוֹלָם עַל רֹאשָׁם, שָׂשׂוֹן וְשִׂמְחָה יַשִּׂיגוּ, וְנָסוּ יָגוֹן וַאֲנָחָה:\n\nהָפַכְתָּ מִסְפְּדִי לְמָחוֹל לִי, פִּתַּחְתָּ שַׂקִּי וַתְּאַזְּרֵנִי שִׂמְחָה: וְלֹא אָבָה יהוה אֱלֹהֶיךָ לִשְׁמֹעַ אֶל בִּלְעָם, וַיַּהֲפֹךְ יהוה אֱלֹהֶיךָ לְּךָ אֶת הַקְּלָלָה לִבְרָכָה, כִּי אֲהֵבְךָ יהוה אֱלֹהֶיךָ: אָז תִּשְׂמַח בְּתוּלָה בְּמָחוֹל וּבַחֻרִים וּזְקֵנִים יַחְדָּו, וְהָפַכְתִּי אֶבְלָם לְשָׂשׂוֹן וְנִחַמְתִּים, וְשִׂמַּחְתִּים מִיגוֹנָם:\n\nבּוֹרֵא נִיב שְׂפָתָיִם, שָׁלוֹם שָׁלוֹם לָרָחוֹק וְלַקָּרוֹב אָמַר יהוה, וּרְפָאתִיו: וְרוּחַ לָבְשָׁה אֶת עֲמָשַׂי רֹאשׁ הַשָּׁלִישִׁים, לְךָ דָוִיד וְעִמְּךָ בֶן יִשַׁי שָׁלוֹם, שָׁלוֹם לְךָ וְשָׁלוֹם לְעֹזְרֶךָ כִּי עֲזָרְךָ אֱלֹהֶיךָ, וַיְקַבְּלֵם דָּוִיד וַיִּתְּנֵם בְּרָאשֵׁי הַגְּדוּד: וַאֲמַרְתֶּם כֹּה לֶחָי, וְאַתָּה שָׁלוֹם, וּבֵיתְךָ שָׁלוֹם וְכֹל אֲשֶׁר לְךָ שָׁלוֹם: יהוה עֹז לְעַמּוֹ יִתֵּן, יהוה יְבָרֵךְ אֶת עַמּוֹ בַשָּׁלוֹם:\n\nאָמַר רַבִּי יוֹחָנָן: בְּכָל מָקוֹם שֶׁאַתָּה מוֹצֵא גְּדֻלָּתוֹ שֶׁל הַקָּדוֹשׁ בָּרוּךְ הוּא, שָׁם אַתָּה מוֹצֵא עַנְוְתָנוּתוֹ. דָּבָר זֶה כָּתוּב בַּתּוֹרָה, וְשָׁנוּי בַּנְּבִיאִים, וּמְשֻׁלָּשׁ בַּכְּתוּבִים. כָּתוּב בַּתּוֹרָה: כִּי יהוה אֱלֹהֵיכֶם הוּא אֱלֹהֵי הָאֱלֹהִים וַאֲדֹנֵי הָאֲדֹנִים, הָאֵל הַגָּדֹל, הַגִּבֹּר וְהַנּוֹרָא, אֲשֶׁר לֹא יִשָּׂא פָנִים וְלֹא יִקַּח שֹׁחַד: וּכְתִיב בָּתְרֵיהּ: עֹשֶׂה מִשְׁפַּט יָתוֹם וְאַלְמָנָה, וְאֹהֵב גֵּר לָתֶת לוֹ לֶחֶם וְשִׂמְלָה: שָׁנוּי בַּנְּבִיאִים, דִּכְתִיב: כִּי כֹה אָמַר רָם וְנִשָּׂא, שֹׁכֵן עַד וְקָדוֹשׁ שְׁמוֹ, מָרוֹם וְקָדוֹשׁ אֶשְׁכּוֹן, וְאֶת דַּכָּא וּשְׁפַל רוּחַ, לְהַחֲיוֹת רוּחַ שְׁפָלִים וּלְהַחֲיוֹת לֵב נִדְכָּאִים: מְשֻׁלָּשׁ בַּכְּתוּבִים, דִּכְתִיב: שִׁירוּ לֵאלֹהִים זַמְּרוּ שְׁמוֹ, סֹלּוּ לָרֹכֵב בָּעֲרָבוֹת בְּיָהּ שְׁמוֹ, וְעִלְזוּ לְפָנָיו: וּכְתִיב בָּתְרֵיהּ: אֲבִי יְתוֹמִים וְדַיַּן אַלְמָנוֹת, אֱלֹהִים בִּמְעוֹן קָדְשׁוֹ:\n\nיְהִי יהוה אֱלֹהֵינוּ עִמָּנוּ כַּאֲשֶׁר הָיָה עִם אֲבֹתֵינוּ, אַל יַעַזְבֵנוּ וְאַל יִטְּשֵׁנוּ: וְאַתֶּם הַדְּבֵקִים בַּיהוה אֱלֹהֵיכֶם, חַיִּים כֻּלְּכֶם הַיּוֹם: כִּי נִחַם יהוה צִיּוֹן, נִחַם כָּל חָרְבֹתֶיהָ, וַיָּשֶׂם מִדְבָּרָהּ כְּעֵדֶן וְעַרְבָתָהּ כְּגַן יהוה, שָׂשׂוֹן וְשִׂמְחָה יִמָּצֵא בָהּ, תּוֹדָה וְקוֹל זִמְרָה: יהוה חָפֵץ לְמַעַן צִדְקוֹ, יַגְדִּיל תּוֹרָה וְיַאְדִּיר:\n\nשִׁיר הַמַּעֲלוֹת, אַשְׁרֵי כָּל יְרֵא יהוה הַהֹלֵךְ בִּדְרָכָיו: יְגִיעַ כַּפֶּיךָ כִּי תֹאכֵל, אַשְׁרֶיךָ וְטוֹב לָךְ: אֶשְׁתְּךָ כְּגֶפֶן פֹּרִיָּה בְּיַרְכְּתֵי בֵיתֶךָ, בָּנֶיךָ כִּשְׁתִלֵי זֵיתִים סָבִיב לְשֻׁלְחָנֶךָ: הִנֵּה כִי כֵן יְבֹרַךְ גָּבֶר יְרֵא יהוה: יְבָרֶכְךָ יהוה מִצִּיּוֹן וּרְאֵה בְּטוּב יְרוּשָׁלָיִם, כֹּל יְמֵי חַיֶּיךָ: וּרְאֵה בָנִים לְבָנֶיךָ, שָׁלוֹם עַל יִשְׂרָאֵל:","cond":["sun"]}]},"edot_mizrach":{"shacharit":[{"kind":"instruction","text":"מיד כשקם בבוקר יאמר מודה אני:","cond":[]},{"kind":"text","text":"מוֹדֶה (נשים אומרות: מוֹדָה) אֲנִי לְפָנֶיךָ מֶלֶךְ חַי וְקַיָּם שֶׁהֶחֱזַרְתָּ בִּי נִשְׁמָתִי בְּחֶמְלָה, רַבָּה אֱמוּנָתֶךָ.","cond":[]},{"kind":"instruction","text":"כל היום אף אם עשה צרכיו אינו מברך על נטילת ידיים רק אשר יצר:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ עַל נְטִילַת יָדָיִם.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלַם, אֲשֶׁר יָצַר אֶת הָאָדָם בְּחָכְמָה, וּבָרָא בוֹ נְקָבִים נְקָבִים, חֲלוּלִים חֲלוּלִים. גָּלוּי וְיָדוּעַ לִפְנֵי כִסֵּא כְבוֹדֶךָ, שֶׁאִם יִסָּתֵם אֶחָד מֵהֶם, אוֹ אִם יִפָּתֵחַ אֶחָד מֵהֶם, אִי אֶפְשָׁר לְהִתְקַיֵּם אֲפִלּוּ שָׁעָה אֶחַת. בָּרוּךְ אַתָּה יהוה, רוֹפֵא כָל-בָּשָׂר וּמַפְלִיא לַעֲשׂוֹת.","cond":[]},{"kind":"instruction","text":"ישתדל להצמיד ברכת אלהי נשמה לברכת אשר יצר. אם שכח ישתדל לברך את ברכת אלהי נשמה בצמוד לברכה אחרת.","cond":[]},{"kind":"text","text":"אֱלֹהַי, נְשָׁמָה שֶׁנָּתַתָּ בִּי טְהוֹרָה. אַתָּה בְרָאתָהּ, אַתָּה יְצַרְתָּהּ, אַתָּה נְפַחְתָּהּ בִּי, וְאַתָּה מְשַׁמְּרָהּ בְּקִרְבִּי, וְאַתָּה עָתִיד לִטְּלָהּ מִמֶּנִּי, וּלְהַחֲזִירָהּ בִּי לֶעָתִיד לָבוֹא. כָּל זְמַן שֶׁהַנְּשָׁמָה בְּקִרְבִּי מוֹדֶה אֲנִי לְפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, רִבּוֹן כָּל הַמַּעֲשִׂים, אֲדוֹן כָּל הַנְּשָׁמוֹת. בָּרוּךְ אַתָּה יהוה, הַמַּחֲזִיר נְשָׁמוֹת לִפְגָרִים מֵתִים.\n\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַנוֹתֵן לַשֶּׂכְוִי בִינָה לְהַבְחִין בֵּין יוֹם וּבֵין לָיְלָה. \nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, פּוֹקֵחַ עִוְרִים. \nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, מַתִּיר אֲסוּרִים.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, זוֹקֵף כְּפוּפִים.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, מַלְבִּישׁ עֲרֻמִּים.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַנּוֹתֵן לַיָּעֵף כֹּחַ.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, רוֹקַע הָאָרֶץ עַל הַמָּיִם.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַמֵּכִין מִצְעֲדֵי גָבֶר.","cond":[]},{"kind":"instruction","text":"יש שאינם מברכים ברכת \"שעשה לי כל צרכי\" בתשעה באב. ויש אומרים שאפשר לברך אם מתכוון במוצאי הצום לנעול את נעליו הרגילות.","cond":["tishaaBeav"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁעָשָׂה לִי כָּל צְרָכָי.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אוֹזֵר יִשְׂרָאֵל בִּגְבוּרָה.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, עוֹטֵר יִשְׂרָאֵל בְּתִפְאָרָה.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁלֹּא עָשַׂנִי גּוֹי (האשה אומרת: גּוֹיָה).\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁלֹּא עָשַׂנִי עָבֶד (האשה אומרת - שִׁפְחָה).","cond":[]},{"kind":"instruction","text":"גברים מברכים:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁלֹּא עָשַׂנִי אִשָּׁה.","cond":[]},{"kind":"instruction","text":"נשים אומרות בלי שם ומלכות:","cond":[]},{"kind":"text","text":"בָּרוּךְ שֶׁעָשַׂנִי כִרְצוֹנוֹ.","cond":[]},{"kind":"instruction","text":"אין עונים אמן לאחר ברכת המעביר חבלי שנה, אלא רק לאחר \"גומל חסדים טובים לעמו ישראל\" מפני שהיא ברכה אחת.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַמַּעֲבִיר חֶבְלֵי שֵׁנָה מֵעֵינָי וּתְנוּמָה מֵעַפְעַפָּי. וִיהִי רָצוֹן מִלְפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁתַּרְגִילֵינִי בְּתוֹרָתֶךְ, וְתַדְבִּיקֵנִי בְּמִצְוׂתֶיךָ. וְאַל תְּבִיאֵנִי לִידֵי חֵטְא, וְלֹא לִידֵי עֲוׂן, וְלֹא לִידֵי נִסָּיוֹן, וְלֹא לִידֵי בִזָּיוֹן. וְתַרְחִיקֵנִי מִיֵּצֶר הָרָע, וְתַדְבִּיקֵנִי בְּיֵצֶר הַטּוֹב. וְכֹף אֶת יִצְרִי לְהִשְׁתַּעְבֶּד לָּךְ. וּתְנֵנִי הַיּוֹם וּבְכָל יוֹם וָיוֹם לְחֵן וּלְחֶסֶד וּלְרַחֲמִים בְּעֵינֶיךָ וּבְעֵינֵי כָל רוֹאַי, וְגָמְלֵנִי חֲסָדִים טוֹבִים. בָּרוּךְ אַתָּה יהוה, גּוֹמֵל חֲסָדִים טוֹבִים לְעַמּוֹ יִשְׂרָאֵל.\n\nיְהִי רָצוֹן מִלְּפָנֶיךָ יהוה, אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁתַּצִּילֵנִי הַיּוֹם וּבְכָל יוֹם וָיוֹם מֵעַזֵּי פָנִים, וּמֵעַזּוּת פָּנִים, מֵאָדָם רָע, מִיֵּצֶר רָע, מֵחָבֵר רָע, מִשָּׁכֵן רָע, מִפֶּגַע רָע, מֵעַיִן הָרָע, וּמִלָּשׁון הָרָע, מִדִּין קָשֶׁה, וּמִבַּעַל דִּין קָשֶׁה, בֵּין שֶׁהוּא בֶן בְּרִית, וּבֵין שֶׁאֵינוֹ בֶן בְּרִית.","cond":[]},{"kind":"instruction","text":"ברכות התורה","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ עַל דִּבְרֵי תוֹרָה.","cond":[]},{"kind":"instruction","text":"אין עונים אמן, אלא ממשיכים מיד לברכת והערב נא, מפני שזו ברכה אחת (שו\"ע סי' מ\"ז סע' ו, ובמשנ\"ב ס\"ק י\"א-י\"ב).","cond":[]},{"kind":"text","text":"וְהַעֲרֵב נָא יהוה אֱלֹהֵינוּ, אֶת דִּבְרֵי תוֹרָתְךָ בְּפִינוּ וּבְפִיפִיּוֹת עַמְּךָ בֵית יִשְׂרָאֵל, וְנִהְיֶה אֲנַחְנוּ, וְצֶאֱצָאֵינוּ, וְצֶאֱצָאֵי צֶאֱצָאֵינוּ, וְצֶאֱצָאֵי עַמְּךָ בֵית יִשְׂרָאֵל, כֻּלָּנוּ יוֹדְעֵי שְׁמֶךָ, וְלוֹמְדֵי תוֹרָתְךָ לִשְׁמָהּ. בָּרוּךְ אַתָּה יהוה, הַמְלַמֵּד תּוֹרָה לְעַמּוֹ יִשְׂרָאֵל.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר בָּחַר בָּנוּ מִכָּל הָעַמִּים, וְנָתַן לָנוּ אֶת תּוֹרָתוֹ. בָּרוּךְ אַתָּה יהוה, נוֹתֵן הַתּוֹרָה.\n\nוַיְדַבֵּר יהוה אֶל מֹשֶׁה לֵּאמֹר: דַּבֵּר אֶל אַהֲרֹן וְאֶל בָּנָיו לֵּאמֹר, כֹּה תְבָרְכוּ אֶת בְּנֵי יִשְׂרָאֵל, אָמוֹר לָהֶם:\nיְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ:\nיָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ:\nיִשָּׂא יהוה פָּנָיו אֵלֶיךָ וְיָשֵׂם לְךָ שָׁלוֹם:\nוְשָׂמוּ אֶת שְׁמִי עַל בְּנֵי יִשְׂרָאֵל, וַאֲנִי אֲבָרֲכֵם:","cond":[]},{"kind":"header","text":"פתיחת אליהו","cond":[]},{"kind":"instruction","text":"פתיחת אליהו הנביא זכור לטוב:\n\nטוב לומר קודם כל תפילה פתיחת אליהו ז\"ל, ומועילה לפתיחת הלב:","cond":[]},{"kind":"text","text":"וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ:\nפָּתַח אֵלִיָּהוּ הַנָּבִיא זָכוּר לַטּוֹב וְאָמַר: רִבּוֹן עָלְמִין דְּאַנְתְּ הוּא חָד וְלָא בְּחֻשְׁבָּן. אַנְתְּ הוּא עִלָּאָה עַל כָּל עִלָּאִין סְתִימָא עַל כָּל סְתִימִין לֵית מַחֲשָׁבָה תְּפִיסָא בָּךְ כְּלָל. אַנְתְּ הוּא דְּאַפַּקְתְּ עֶשֶׂר תִּקּוּנִין וְקָרֵינָן לוֹן עֶשֶׂר סְפִירָן לְאַנְהָגָא בְהוֹן עָלְמִין סְתִימִין דְּלָא אִתְגַּלְיָן וְעָלְמִין דְּאִתְגַּלְיָן. וּבְהוֹן אִתְכַּסִּיאַת מִבְּנֵי נָשָׁא. וְאַנְתְּ הוּא דְקָשִׁיר לוֹן וּמְיַחֵד לוֹן. וּבְגִין דְּאַנְתְּ מִלְּגָאו כָּל מָאן דְּאַפְרִישׁ חַד מִן חַבְרֵיהּ מֵאִלֵּין עֶשֶׂר אִתְחַשִׁיב לֵיהּ כְּאִלּוּ אַפְרִישׁ בָּךְ. וְאִלֵּין עֶשֶׂר סְפִירָן אִנּוּן אַזְלִין כְּסִדְרָן חַד אָרִיךְ וְחָד קָצֵר וְחַד בֵּינונִי. וְאַנְתְּ הוּא דְּאַנְהִיג לוֹן. וְלֵית מָאן דְּאַנְהִיג לָךְ לָא לְעֵילָּא וְלָא לְתַתָּא וְלָא מִכָּל סִטְרָא. לְבוּשִׁין תַּקַּנְתְּ לוֹן דְּמִנַּיְהוּ פַרְחִין נִשְׁמָתִין לִבְנֵי נָשָׁא. וְכַמָּה גוּפִין תַּקַּנְתְּ לוֹן דְּאִתְקְרִיאוּ גוּפָא לְגַבֵּי לְבוּשִׁין דִּמְכַסְיָן עֲלֵיהון וְאִתְקְרִיאוּ בְּתִקּוּנָא דָא. חֶסֶד דְּרוֹעָא יְמִינָא. גְּבוּרָה דְרוֹעָא שְׂמָאלָא. תִּפְאֶרֶת גּוּפָא. נֶצַח וְהוֹד תְּרֵין שׁוֹקִין. יְסוֹד סִיּוּמָא דְּגוּפָא אוֹת בְּרִית קֹדֶשׁ. מַלְכוּת פֶּה תּוֹרָה שֶׁבְּעַל פֶּה קָרֵינָן לָהּ. חָכְמָה מוֹחָא אִיהִי מַחֲשָׁבָה מִלְּגָאו. בִּינָה לִבָּא וּבָהּ הַלֵּב מֵבִין. וְעַל אִלֵּין תְּרֵין כְּתִיב \"הַנִּסְתָּרות לַיהוה אֱלֹהֵינוּ\". כֶּתֶר עֶלְיוֹן אִיהוּ כֶּתֶר מַלְכוּת. וְעָלֵיהּ אִתְמַר \"מַגִּיד מֵרֵאשִׁית אַחֲרִית\". וְאִיהוּ קַרְקַפְתָּא דִתְפִלֵּי. מִלְּגָאו אִיהוּ אוֹת יוֹ\"ד אוֹת הֵ\"א אוֹת וָא\"ו וְאוֹת הֵ\"א דְּאִיהוּ אֹרַח אֲצִילוּת. אִיהוּ שַׁקְיוּ דְּאִילָנָא בִּדְרוֹעוֹי וְעַנְפּוֹי. כְּמַיָּא דְאַשְׁקֵי לְאִילָנָא וְאִתְרַבֵּי בְּהַהוּא שַׁקְיוּ.\n\nרִבּוֹן עָלְמִין אַנְתְּ הוּא עִלַּת הָעִלּוֹת וְסִבַּת הַסִּבּוֹת דְאַשְׁקֵי לְאִילָנָא בְּהַהוּא נְבִיעוּ. וְהַהוּא נְבִיעוּ אִיהוּ כְּנִשְׁמְתָא לְגוּפָא דְּאִיהוּ חַיִּים לְגוּפָא. וּבָךְ לֵית דִּמְיוֹן וְלֵית דִּיּוּקְנָא (דְּגוּפָא) מִכָּל מַה דִלְגָאו וּלְבַר. וּבָרָאתָ שְׁמַיָּא וְאַרְעָא. וְאַפַּקְתְּ מִנְּהוֹן שִׁמְשָׁא וְסִיהֲרָא וְכוֹכְבַיָּא וּמַזָּלֵי. וּבְאַרְעָא אִילָנִין וּדְשָׁאִין וְגִנְּתָא דְעֵדֶן וְעִשְׂבִּין וְחֵיוָן וְעוֹפִין וְנוּנִין וּבְעִירִין וּבְנֵי נָשָׁא. לְאִשְׁתְּמוֹדְעָא בְּהוֹן עִלָּאִין וְאֵיךְ יִתְנַהֲגוּן בְּהוֹן עִלָּאִין וְתַתָּאִין. וְאֵיךְ אִשְׁתְּמוֹדְעָן מֵעִלָּאֵי וְתַתָּאֵי וְלֵית דְּיָדַע בָּךְ כְּלָל. וּבַר מִנָּךְ לֵית יִחוּדָא בְּעִלָּאֵי וְתַתָּאֵי. וְאַנְתְּ אִשְׁתְּמוֹדָע אָדוֹן עַל כֹּלָּא. וְכָל סְפִירָן כָּל חַד אִית לֵיהּ שֵׁם יְדִיעַ. וּבְהוֹן אִתְקְרִיאוּ מַלְאָכַיָּא. וְאַנְתְּ לֵית לָךְ שֵׁם יְדִיעַ דְּאַנְתְּ הוּא מְמַלֵּא כָּל שְׁמָהָן וְאַנְתְּ הוּא שְׁלִימוּ דְּכֻלְהוּ. וְכַד אַנְתְּ תִּסְתַּלָּק מִנְּהוֹן. אִשְׁתְּאָרוּ כֻּלְּהוּ שְׁמָהָן כְּגוּפָא בְלָא נִשְׁמָתָא. אַנְתְּ חַכִּים וְלָאו בְּחָכְמָה יְדִיעָא. אַנְתְּ הוּא מֵבִין וְלָאו מִבִּינָה יְדִיעָא. לֵית לָךְ אֲתָר יְדִיעָא. אֶלָּא לְאִשְׁתְּמוֹדְעָא תָּקְפָּךְ וְחֵילָךְ לִבְנֵי נָשָׁא. וּלְאַחְזָאָה לוֹן אֵיךְ אִתְנְהִיג עָלְמָא בְדִינָא וּבְרַחֲמֵי דְאִינוּן צֶדֶק וּמִשְׁפָּט כְּפוּם עוֹבָדֵיהוֹן דִּבְנֵי נָשָׁא. דִּין אִיהוּ גְבוּרָה. מִשְׁפָּט עַמּוּדָא דְאֶמְצָעִיתָא. צֶדֶק מַלְכוּתָא קַדִּישָׁא מֹאזְנֵי צֶדֶק תְּרֵין סַמְכֵי קְשׁוֹט. הִין צֶדֶק אוֹת בְּרִית. כֹּלָּא לְאַחְזָאָה אֵיךְ אִתְנְהִיג עָלְמָא. אֲבָל לָאו דְּאִית לָךְ צֶדֶק יְדִיעָא דְּאִיהוּ דִין. וְלָאו מִשְׁפָּט יְדִיעָא דְאִיהוּ רַחֲמֵי. וְלָאו מִכָּל אִלֵּין מִדּוֹת כְּלָל. קוּם רִבִּי שִׁמְעון וְיִתְחַדְּשׁוּן מִלִּין עַל יְדָךְ. דְהָא רְשׁוּתָא אִית לָךְ לְגַלָּאָה רָזִין טְמִירִין עַל יְדָךְ מַה דְלָא אִתְיְהִיב רְשׁוּ לְגַלָּאָה לְשׁוּם בַּר נָשׁ עַד כְּעָן.\n\nקָם רִבִּי שִׁמְעון פָּתַח וְאָמַר: לְךָ יהוה הַגְּדֻלָּה וְהַגְּבוּרָה וְהַתִּפְאֶרֶת וְהַנֵּצַח וְהַהוֹד כִּי כֹל בַּשָּׁמַיִם וּבָאָרֶץ: לְךָ יהוה הַמַּמְלָכָה, וְהַמִּתְנַשֵּׂא לְכֹל עִלָּאִין שְׁמָעוּ אִנּוּן דְּמִיכִין דְּחֶבְרוֹן וְרַעְיָא מְהֵימְנָא אִתְּעָרוּ מִשְּׁנַתְכוֹן. הָקִיצוּ וְרַנְּנוּ שׁוֹכְנֵי עָפָר. אִלֵּין אִנּוּן צַדִּיקַיָּא דְּאִנּוּן מִסִּטְרָא דְהַהוּא דְּאִתְמַר בָּהּ \"אֲנִי יְשֵׁנָה וְלִבִּי עֵר\". וְלָאו אִנּוּן מֵתִים. וּבְגִין דָּא אִתְּמַר בְּהוֹן \"הָקִיצוּ וְרַנְּנוּ\" וְגו'. רַעְיָא מְהֵימְנָא אַנְתְּ וַאֲבָהָן הָקִיצוּ וְרַנְּנוּ לְאִתְּעָרוּתָא דִּשְׁכִינְתָּא דְּאִיהִי יְשֵׁנָה בְגָלוּתָא. דְּעַד כְּעַן צַדִּיקַיָּא כֻּלְּהוּ דְמִיכִין וְשִׁנְתָּא בְחוֹרֵיהוֹן. מִיָּד יָהִיבַת שְׁכִינְתָּא תְּלַת קָלִין לְגַבֵּי רַעְיָא מְהֵימְנָא וְיִימָא לֵיהּ: קוּם רַעְיָא מְהֵימְנָא - דְהָא עֲלָךְ אִתְּמַר \"קוֹל דּוֹדִי דוֹפֵק\" לְגַבָּאי בְּאַרְבָּע אַתְוָן דִּילֵיהּ. וְיִימָא בְהוֹן \"פִּתְחִי לִי אֲחותִי רַעְיָתִי יוֹנָתִי תַמָּתִי\". דְהָא תַּם עֲוׂנֵךְ בַּת צִיּוֹן לֹא יוֹסִיף לְהַגְלוֹתֵךְ. שֶׁרֹּאשִׁי נִמְלָא טָל. מַאי \"נִמְלָא טָל\"? אֶלָּא אָמַר קֻדְשָׁא בְרִיךְ הוּא, אַנְתְּ חָשַׁבְתְּ דְּמִיּוֹמָא דְאִתְחָרַב בֵּי מַקְדְּשָׁא דְּעָאלְנָא בְּבֵיתָא דִילִי וְעָאלְנָא בְיִשּׁוּבָא, לָאו הֲכִי, דְּלָא עָאלְנָא כָּל זִמְנָא דְּאַנְתְּ בְּגָלוּתָא. הֲרֵי לָךְ סִימָנָא: שֶׁרֹּאשִׁי נִמְלָא טָל, הֵ\"א שְׁכִינְתָא בְּגָלוּתָא. שְׁלִימוּ דִילָהּ וְחַיִּים דִּילָהּ אִיהוּ טַל. וְדָא אִיהוּ אוֹת יוֹ\"ד אוֹת הֵ\"א אוֹת וָא\"ו וְאוֹת הֵ\"א אִיהִי שְׁכִינְתָּא דְלָא מֵחֻשְׁבָּן ט\"ל, אֶלָּא אוֹת יוֹ\"ד אוֹת הֵ\"א וְאוֹת וָא\"ו דִּסְלִיקוּ אַתְוָן לְחֻשְׁבָּן טָ\"ל. דְּאִיהִי מַלְיָא לִשְׁכִינְתָּא מִנְּבִיעוּ דְּכָל מְקוֹרִין עִלָּאִין. מִיַּד קָם רַעְיָא מְהֵימְנָא וַאֲבָהָן קַדִּישִׁין עִמֵּיהּ. עַד כָּאן רָזָא דְיִחוּדָא. בָּרוּךְ יהוה לְעוֹלָם אָמֵן וְאָמֵן:\n\nוִיהֵא רַעֲוָא מִן קֳדָם עַתִּיקָא קַדִּישָׁא דְכָל קַדִּישִׁין, טְמִירָא דְכָל טְמִירִין, סְתִימָא דְכֹלָּא, דְּיִתְמְשַׁךְ טַלָּא עִלָּאָה מִנֵּהּ לְמַלְיָא רֵישֵׁהּ דִּזְעֵיר אַנְפִּין, וּלְהָטִיל לַחֲקַל תַּפּוּחִין קַדִּישִׁין בִּנְהִירוּ דְאַנְפִּין בְּרַעֲוָא וּבְחֶדְוְתָא דְכֹלָּא. וְיִתְמְשַׁךְ מִן קֳדָם עַתִּיקָא קַדִּישָׁא דְכָל קַדִּישִׁין, טְמִירָא דְכָל טְמִירִין סְתִימָא דְכֹלָּא, רְעוּתָא וְרַחֲמֵי חִנָּא וְחִסְדָּא בִּנְהִירוּ עִלָּאָה בִּרְעוּתָא וְחֶדְוָה, עָלַי וְעַל כָּל בְּנֵי בֵיתִי, וְעַל כָּל הַנִּלְוִים אֵלַי, וְעַל כָּל בְּנֵי יִשְׂרָאֵל עַמֵּהּ. וְיִפְרְקִינָן מִכָּל עַקְתִּין בִּישִׁין דְּיֵיתוּן לְעָלְמָא. וְיַזְמִין וְיִתְיְהִיב לָנָא מְזוֹנָא וּפַרְנָסָתָא טַבְתָּא, בְּלִי צָרָה וְעַקְתָּא, מִמַּזָּלָא דְכָל מְזוֹנֵי בֵּהּ תַּלְיָן. וִישֵזְבִינָן מֵעֵינָא בִישָׁא וּמֵחַרְבָּא דְמַלְאַךְ הַמָּוֶת וּמִדִּינָהּ שֶׁל גֵיהִנָּם. וְיַיְתֵי לָנָא וּלְכָל נַפְשָׁתָנָא חִנָּא וְחִסְדָּא וְחַיֵּי אֲרִיכֵי וּמְזוֹנֵי רְוִיחֵי וְרַחֲמֵי מִן קֳדָמֵהּ. אָמֵן כֵּן יְהִי רָצוֹן, אָמֵן וְאָמֵן.","cond":[]},{"kind":"instruction","text":"קדיש על ישראל","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.\nעַל יִשְׂרָאֵל וְעַל רַבָּנָן וְעַל תַּלְמִידֵיהוֹן וְעַל כָּל תַּלְמִידֵי תַלְמִידֵיהוֹן, דְּעָסְקִין בְּאוֹרַיְתָא קַדִּישְׁתָּא, דִּי בְאַתְרָא הָדֵין וְדִי בְכָל אֲתַר וַאֲתַר, יְהֵא לָנָא וּלְכוֹן וּלְהוֹן, חִנָּא וְחִסְדָּא וְרַחֲמֵי, מִן קֳדָם אֱלָהָא מָארֵי שְׁמַיָּא וְאַרְעָא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא, חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה וְשֵיזָבָא וּרְפוּאָה וּגְאֻלָּה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה, לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"instruction","text":"אדון עולם","cond":[]},{"kind":"text","text":"אֲדוֹן עולָם אֲשֶׁר מָלַךְ, בְּטֶרֶם כָּל יְצִיר נִבְרָא. לְעֵת נַעֲשָׂה בְחֶפְצו כֹּל, אֲזַי מֶלֶךְ שְׁמו נִקְרָא. וְאַחֲרֵי כִּכְלות הַכֹּל, לְבַדּוֹ יִמְלֹךְ נוֹרָא. וְהוּא הָיָה וְהוּא הֹוֶה, וְהוּא יִהְיֶה בְּתִפְאָרָה. וְהוּא אֶחָד וְאֵין שֵׁנִי, לְהַמְשִׁילוֹ וּלְהַחְבִּירָה. בְּלִי רֵאשִׁית בְּלִי תַכְלִית, וְלוֹ הָעֹז וְהַמִּשְׂרָה, בְּלִי עֵרֶךְ בְּלִי דִמְיוֹן, בְּלִי שִׁנּוּי וּתְמוּרָה. בְּלִי חִבּוּר בְּלִי פֵּרוּד, גְּדוֹל כֹּחַ וּגְבוּרָה. וְהוּא אֵלִי וְחַי גּוֹאֲלִי, וְצוּר חֶבְלִי בְּיוֹם צָרָה. וְהוּא נִסִּי וּמָנוּסִי, מְנָת כּוֹסִי בְּיוֹם אֶקְרָא. וְהוּא רוֹפֵא וְהוּא מַרְפֵּא, וְהוּא צוֹפֶה וְהוּא עֶזְרָה. בְּיָדוֹ אַפְקִיד רוּחִי, בְּעֵת אִישָׁן וְאָעִירָה. וְעִם רוּחִי גְוִיָּתִי, אֲדֹנָי לִי וְלֹא אִירָא. בְּמִקְדָּשׁוֹ תָגֵל נַפְשִׁי. מְשִׁיחֵנוּ יִשְׁלַח מְהֵרָה. וְאָז נָשִׁיר בְּבֵית קָדְשִׁי, אָמֵן אָמֵן שֵׁם הַנּוֹרָא.","cond":[]},{"kind":"header","text":"עטיפת טלית והנחת תפילין","cond":["tfilin"]},{"kind":"instruction","text":"עטיפת טלית והנחת תפילין\n\n\nלפני שיברך על הציצית יאמר לשם יחוד זה:","cond":["tfilin"]},{"kind":"text","text":"לְשֵׁם יִחוּד קֻדְשָׁא בְרִיךְ הוּא וּשְׁכִינְתֵּהּ, בִּדְחִילוּ וּרְחִימוּ, וּרְחִימוּ וּדְחִילוּ, לְיַחֲדָא שֵׁם אוֹת י' וְאוֹת ה' בְּשֵׁם אוֹת ו' וְאוֹת ה' בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל יִשְׂרָאֵל, לַאֲקָמָא שְׁכִינְתָּא מִעַפְרָא וּלְעִלּוּי שְׁכִינַת עֻזֵּנוּ, הֲרֵינִי מוּכָן לִלְבֹּשׁ טַלִּית מְצֻיֶּצֶת כְּהִלְכָתָהּ, כְּמו שֶׁצִּוָּנוּ יהוה אֱלֹהֵינוּ בְּתוֹרָתוֹ הַקְּדוֹשָׁה: \"וְעָשׂוּ לָהֶם צִיצִת עַל כַּנְפֵי בִגְדֵיהֶם\". וְעַל יְדֵי עֲטִיפַת הַצִּיצִית נִזְכֹּר כָּל מִצְוׂתָיו לַעֲשׂוֹתָן, כְּדֵי לַעֲשׂוֹת נַחַת רוּחַ לְיוֹצְרִי וְלַעֲשׂוֹת רְצוֹן בּוֹרְאִי. וַהֲרֵינִי מוּכָן לְבָרֵךְ עַל עֲטִיפַת הַטַּלִּית כְּתִקּוּן רַבּוֹתֵינוּ זִכְרוֹנָם לִבְרָכָה. וַהֲרֵינִי מְכַוֵּן לִפְטֹר בִּבְרָכָה זוֹ גַּם טַלִּית קָטָן שֶׁעָלַי. וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ: וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ:\n\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ לְהִתְעַטֵּף בְּצִּיצִית.","cond":["tfilin"]},{"kind":"instruction","text":"יתעטף בטלית ויכסה בה את ראשו ויישאר כך מעוטף ויאמר:","cond":["tfilin"]},{"kind":"text","text":"יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה: יהוה צְבָאוֹת אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":["tfilin"]},{"kind":"instruction","text":"אחרי שמוריד הטלית על גופו יאמר:","cond":["tfilin"]},{"kind":"text","text":"מַה יָּקָר חַסְדְּךָ אֱלֹהִים, וּבְנֵי אָדָם בְּצֵל כְּנָפֶיךָ יֶחֱסָיוּן: יִרְוְיֻן מִדֶּשֶׁן בֵּיתֶךָ וְנַחַל עֲדָנֶיךָ תַשְׁקֵם: כִּי עִמְּךָ מְקוֹר חַיִּים, בְּאוֹרְךָ נִרְאֶה אוֹר: מְשֹׁךְ חַסְדְּךָ לְיֹדְעֶיךָ וְצִדְקָתְךָ לְיִשְׁרֵי לֵב:","cond":["tfilin"]},{"kind":"instruction","text":"ויש מוסיפים:","cond":["tfilin"]},{"kind":"text","text":"שׂוֹשׂ אָשִׂישׂ בַּיהוה תָּגֵל נַפְשִׁי בֵּאלֹהַי, כִּי הִלְבִּישַׁנִי בִּגְדֵי יֶשַׁע מְעִיל צְדָקָה יְעָטָנִי, כֶּחָתָן יְכַהֵן פְּאֵר וְכַכַּלָּה תַּעְדֶּה כֵלֶיהָ:","cond":["tfilin"]},{"kind":"instruction","text":"לפני הנחת תפילין של יד יאמר:","cond":["tfilin"]},{"kind":"text","text":"לְשֵׁם יִחוּד קֻדְשָׁא בְרִיךְ הוּא וּשְׁכִינְתֵּהּ, בִּדְחִילוּ וּרְחִימוּ, וּרְחִימוּ וּדְחִילוּ, לְיַחֲדָא שֵׁם אוֹת י' וְאוֹת ה' בְּשֵׁם אוֹת ו' וְאוֹת ה' בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל יִשְׂרָאֵל, הֲרֵינִי מוּכָן לְקַיֵּם מִצְוַת עֲשֵׂה לְהָנִיחַ תְּפִלִּין בְּיָדִי וּבְרֹאשִׁי, כְּמוֹ שֶׁצִּוָּנוּ יהוה אֱלֹהֵינוּ: \"וּקְשַׁרְתֶּם אֹתָם לְאוֹת עַל יֶדְכֶם, וְהָיוּ לְטוֹטָפֹת בֵּין עֵינֵיכֶם:\" וַאֲנִי מְכַוֵּן בַּהַנָּחַת אַרְבַּע פָּרָשִׁיּוֹת אֵלּוּ, שֶׁיֵּשׁ בָּהֶן יִחוּד שְׁמוֹ וִיצִיאַת מִצְרַיִם, לְהַנִּיחָן עַל הַזְּרוֹעַ כְּנֶגֶד הַלֵּב וְעַל הָרֹאשׁ כְּנֶגֶד הַמֹּחַ, כְּדֵי שֶׁנִּזְכֹּר נִסִּים וְנִפְלָאוֹת שֶׁעָשָׂה עִמָּנוּ, שֶׁהֵם מוֹרִים עַל יִחוּדוֹ וַאֲשֶׁר לוֹ הַכֹּחַ וְהַמֶּמְשָׁלָה בָּעֶלְיוֹנִים וּבַתַּחְתּוֹנִים לַעֲשׂוֹת בָּהֶם כִּרְצוֹנוֹ. וַהֲרֵינִי מְשַׁעְבֵּד לַקָּדוֹשׁ בָּרוּךְ הוּא הַנְּשָׁמָה שֶׁהִיא בַּמֹּחַ, וְהַלֵּב שֶׁהוֹא כְּנֶגֶד הַזְּרוֹעַ, שֶׁהֵם עִקַּר הַתַּאֲווֹת וְהַמַּחֲשָׁבוֹת, וּבָזֶה נִזְכֹּר הַבּוֹרֵא וּנְמַעֵט הֲנָאוֹתֵינוּ. וַהֲרֵינִי מוּכָן לְבָרֵךְ הַבְּרָכָה שֶׁתִּקְּנוּ חֲכָמֵינוּ זִכְרוֹנָם לִבְרָכָה עַל הַתְּפִלִּין. וַהֲרֵינִי מְכַוֵּן לִפְטֹר בִּבְרָכָה זוֹ תְּפִלִּין שֶׁל יָד וּתְפִלִּין שֶׁל רֹאשׁ. וְיַעֲלֶה לְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ כְּאִלּוּ כִּוַּנְתִּי בְּכָל הַכַּוָּנוֹת הָרְאוּיוֹת לְכַוֵּן בְּהַנָּחַת הַתְּפִלִּין וּבַבְּרָכָה. וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ: וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ:\n\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ לְהָנִיחַ תְּפִלִּין.","cond":["tfilin"]},{"kind":"instruction","text":"ואם הפסיק בדיבור בין תפילין של יד לתפילין של ראש יברך:","cond":["tfilin"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ עַל מִצְוַת תְּפִלִּין.","cond":["tfilin"]},{"kind":"instruction","text":"אחרי הידוק תפילין של ראש יאמר:","cond":["tfilin"]},{"kind":"text","text":"וּמֵחָכְמָתְךָ אֵל עֶלְיוֹן תַּאֲצִיל עָלַי, וּמִבִּינָתְךָ תְּבִינֵנִי, וּבְחַסְדְּךָ תַּגְדִּיל עָלַי, וּבִגְבוּרָתְךָ תַּצְמִית אוֹיְבַי וְקָמַי. וְשֶׁמֶן הַטּוֹב וְהַטָּהוֹר תָּרִיק עַל שִׁבְעַת קְנֵי מְנוֹרָה, לְהַשְׁפִּיעַ טוּבְךָ לִבְרִיּוֹתֶיךָ. פּוֹתֵחַ אֶת יָדֶךָ וּמַשְׂבִּיעַ לְכָל חַי רָצוֹן:","cond":["tfilin"]},{"kind":"instruction","text":"כשיכרוך שלש כריכות על אצבעו האמצעית יאמר:","cond":["tfilin"]},{"kind":"text","text":"וְאֵרַשְׂתִּיךְ לִי לְעוֹלָם: וְאֵרַשְׂתִּיךְ לִי בְּצֶדֶק וּבְמִשְׁפָּט וּבְחֶסֶד וּבְרַחֲמִים: וְאֵרַשְׂתִּיךְ לִי בֶּאֱמוּנָה, וְיָדַעְתְּ אֶת יהוה:","cond":["tfilin"]},{"kind":"instruction","text":"אחר הנחת תפילין יאמר שתי פרשיות אלו, ואם אינו יכול לאומרן קודם התפילה יאמר אותן אחר התפלה, לפני שיחלוץ התפילין:","cond":["tfilin"]},{"kind":"text","text":"וַיְדַבֵּר יהוה אֶל מֹשֶׁה לֵּאמֹר: קַדֶּשׁ לִי כָל בְּכוֹר פֶּטֶר כָּל רֶחֶם בִּבְנֵי יִשְׂרָאֵל בָּאָדָם וּבַבְּהֵמָה, לִי הוּא: וַיֹּאמֶר מֹשֶׁה אֶל הָעָם זָכוֹר אֶת הַיּוֹם הַזֶּה אֲשֶׁר יְצָאתֶם מִמִּצְרַיִם מִבֵּית עֲבָדִים, כִּי בְּחֹזֶק יָד הוֹצִיא יהוה אֶתְכֶם מִזֶּה, וְלֹא יֵאָכֵל חָמֵץ: הַיּוֹם אַתֶּם יֹצְאִים, בְּחֹדֶשׁ הָאָבִיב: וְהָיָה כִי יְבִיאֲךָ יהוה אֶל אֶרֶץ הַכְּנַעֲנִי וְהַחִתִּי וְהָאֱמֹרִי וְהַחִוִּי וְהַיְבוּסִי אֲשֶׁר נִשְׁבַּע לַאֲבֹתֶיךָ לָתֶת לָךְ, אֶרֶץ זָבַת חָלָב וּדְבָשׁ, וְעָבַדְתָּ אֶת הָעֲבֹדָה הַזֹּאת בַּחֹדֶשׁ הַזֶּה: שִׁבְעַת יָמִים תֹּאכַל מַצֹּת וּבַיּוֹם הַשְּׁבִיעִי חַג לַיהוה: מַצּוֹת יֵאָכֵל אֵת שִׁבְעַת הַיָּמִים, וְלֹא יֵרָאֶה לְךָ חָמֵץ וְלֹא יֵרָאֶה לְךָ שְׂאֹר בְּכָל גְּבֻלֶךָ: וְהִגַּדְתָּ לְבִנְךָ בַּיּוֹם הַהוּא לֵאמֹר, בַּעֲבוּר זֶה עָשָׂה יהוה לִי בְּצֵאתִי מִמִּצְרָיִם: וְהָיָה לְךָ לְאוֹת עַל יָדְךָ וּלְזִכָּרוֹן בֵּין עֵינֶיךָ, לְמַעַן תִּהְיֶה תּוֹרַת יהוה בְּפִיךָ, כִּי בְּיָד חֲזָקָה הוֹצִאֲךָ יהוה מִמִּצְרָיִם: וְשָׁמַרְתָּ אֶת הַחֻקָּה הַזֹּאת לְמוֹעֲדָהּ, מִיָּמִים יָמִימָה:\n\nוְהָיָה כִּי יְבִאֲךָ יהוה אֶל אֶרֶץ הַכְּנַעֲנִי כַּאֲשֶׁר נִשְׁבַּע לְךָ וְלַאֲבֹתֶיךָ, וּנְתָנָהּ לָךְ: וְהַעֲבַרְתָּ כָל פֶּטֶר רֶחֶם לַיהוה, וְכָל פֶּטֶר שֶׁגֶר בְּהֵמָה אֲשֶׁר יִהְיֶה לְךָ הַזְּכָרִים לַיהוה: וְכָל פֶּטֶר חֲמֹר תִּפְדֶּה בְשֶׂה, וְאִם לֹא תִפְדֶּה וַעֲרַפְתּוֹ, וְכֹל בְּכוֹר אָדָם בְּבָנֶיךָ תִּפְדֶּה: וְהָיָה כִּי יִשְׁאָלְךָ בִנְךָ מָחָר לֵּאמֹר מַה זֹּאת, וְאָמַרְתָּ אֵלָיו, בְּחֹזֶק יָד הוֹצִיאָנוּ יהוה מִמִּצְרַיִם מִבֵּית עֲבָדִים: וַיְהִי כִּי הִקְשָׁה פַרְעֹה לְשַׁלְּחֵנוּ, וַיַּהֲרֹג יהוה כָּל בְּכוֹר בְּאֶרֶץ מִצְרַיִם, מִבְּכֹר אָדָם וְעַד בְּכוֹר בְּהֵמָה, עַל כֵּן אֲנִי זֹבֵחַ לַיהוה כָּל פֶּטֶר רֶחֶם הַזְּכָרִים וְכָל בְּכוֹר בָּנַי אֶפְדֶּה: וְהָיָה לְאוֹת עַל יָדְכָה וּלְטוֹטָפֹת בֵּין עֵינֶיךָ, כִּי בְּחֹזֶק יָד הוֹצִיאָנוּ יהוה מִמִּצְרָיִם:","cond":["tfilin"]},{"kind":"instruction","text":"כשנכנס לבית הכנסת יעמוד בפתח ויאמר פסוק ואני ברוב חסדך וכו', וישתחוה ואחר כך יכנס, לא יאמר פסוק זה אלא אם כן לבוש ציצית ותפילין.","cond":["tfilin"]},{"kind":"text","text":"וַאֲנִי בְּרֹב חַסְדְּךָ אָבוֹא בֵיתֶךָ. אֶשְׁתַּחֲוֶה אֶל הֵיכַל קָדְשְׁךָ בְּיִרְאָתֶךָ:","cond":["tfilin"]},{"kind":"instruction","text":"כשנכנס לבית הכנסת יאמר בזמן הליכתו ג' פסוקים אלה:","cond":[]},{"kind":"text","text":"יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה: יהוה צְבָאוֹת, אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":[]},{"kind":"instruction","text":"תפילת חנה","cond":[]},{"kind":"text","text":"וַתִּתְפַּלֵּל חַנָּה וַתֹּאמַר, עָלַץ לִבִּי בַּיהוה, רָמָה קַרְנִי בַּיהוה, רָחַב פִּי עַל אוֹיְבַי כִּי שָׂמַחְתִּי בִּישׁוּעָתֶךָ: אֵין קָדוֹשׁ כַּיהוה כִּי אֵין בִּלְתֶּךָ, וְאֵין צוּר כֵּאלֹהֵינוּ: אַל תַּרְבּוּ תְדַבְּרוּ גְּבֹהָה גְבֹהָה יֵצֵא עָתָק מִפִּיכֶם, כִּי אֵל דֵּעוֹת יהוה וְלוֹ נִתְכְּנוּ עֲלִלוֹת: קֶשֶׁת גִּבֹּרִים חַתִּים וְנִכְשָׁלִים אָזְרוּ חָיִל: שְׂבֵעִים בַּלֶּחֶם נִשְׂכָּרוּ וּרְעֵבִים חָדֵלּוּ, עַד עֲקָרָה יָלְדָה שִׁבְעָה וְרַבַּת בָּנִים אֻמְלָלָה: יהוה מֵמִית וּמְחַיֶּה, מוֹרִיד שְׁאוֹל וַיָּעַל: יהוה מוֹרִישׁ וּמַעֲשִׁיר, מַשְׁפִּיל אַף מְרוֹמֵם: מֵקִים מֵעָפָר דָּל מֵאַשְׁפֹּת יָרִים אֶבְיוֹן, לְהוֹשִׁיב עִם נְדִיבִים וְכִסֵּא כָבוֹד יַנְחִלֵם, כִּי לַיהוה מְצֻקֵי אֶרֶץ וַיָּשֶׁת עֲלֵיהֶם תֵּבֵל: רַגְלֵי חֲסִידָיו יִשְׁמֹר וּרְשָׁעִים בַּחֹשֶׁךְ יִדָּמּוּ, כִּי לֹא בְכֹחַ יִגְבַּר אִישׁ: יהוה יֵחַתּוּ מְרִיבָיו, עָלָיו בַּשָּׁמַיִם יַרְעֵם, יהוה יָדִין אַפְסֵי אָרֶץ, וְיִתֶּן עֹז לְמַלְכּוֹ וְיָרֵם קֶרֶן מְשִׁיחוֹ:\nאָתוֹהִי כְּמָה רַבְרְבִין וְתִמְהוֹהִי כְּמָה תַקִּיפִין, מַלְכוּתֵהּ מַלְכוּת עָלַם וְשָָלְטָנֵהּ עִם דָּר וְדָר:\nוַאֲנַחְנוּ עַמְּךָ וְצֹאן מַרְעִיתֶךָ, נוֹדֶה לְּךָ לְעוֹלָם, לְדֹר וָדֹר נְסַפֵּר תְּהִלָּתֶךָ:\nעֶרֶב וָבֹקֶר וְצָהֳרַיִם אָשִׂיחָה וְאֶהֱמֶה, וַיִּשְׁמַע קוֹלִי:\nבְּרָן יַחַד כּוֹכְבֵי בֹקֶר, וַיָּרִיעוּ כָּל בְּנֵי אֱלֹהִים.\nלֹא אִירָא מֵרִבְבוֹת עָם אֲשֶׁר סָבִיב שָׁתוּ עָלָי:\nוַאֲנִי בַּיהוה אֲצַפֶּה, אוֹחִילָה לֵאלֹהֵי יִשְׁעִי, יִשְׁמָעֵנִי אֱלֹהָי:\nאַל תִּשְׂמְחִי אֹיַבְתִּי לִי כִּי נָפַלְתִּי קָמְתִּי, כִּי אֵשֵׁב בַּחֹשֶׁךְ יהוה אוֹר לִי:\nכִּי לְךָ יהוה הוֹחָלְתִּי, אַתָּה תַעֲנֶה אֲדֹנָי אֱלֹהָי:\nרַגְלִי עָמְדָה בְמִישׁוֹר, בְּמַקְהֵלִים אֲבָרֵךְ יהוה:","cond":[]},{"kind":"instruction","text":"לפני התפלה יאמר:","cond":[]},{"kind":"text","text":"לְשֵׁם יִחוּד קֻדְשָׁא בְרִיךְ הוּא וּשְׁכִינְתֵּהּ, בִּדְחִילוּ וּרְחִימוּ, וּרְחִימוּ וּדְחִילוּ, לְיַחֲדָא שֵׁם אוֹת י' וְאוֹת ה' בְּשֵׁם אוֹת ו' וְאוֹת ה' בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל יִשְׂרָאֵל, הִנֵּה אֲנַחְנוּ בָּאִים לְהִתְפַּלֵּל תְּפִלַּת שַׁחֲרִית, שֶׁתִּקֵּן אַבְרָהָם אָבִינוּ עָלָיו הַשָּׁלוֹם, עִם כָּל הַמִּצְוׂת הַכְּלוּלוֹת בָּהּ, לְתַקֵּן אֶת שָׁרְשָׁהּ בְּמָקוֹם עֶלְיוֹן, לַעֲשׂוֹת נַחַת רוּחַ לְיוֹצְרֵנוּ, וְלַעֲשׂוֹת רְצוֹן בּוֹרְאֵנוּ. וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ:\n\nהֲרֵינִי מְקַבֵּל עָלַי מִצְוַת עֲשֵׂה שֶׁל \"וְאָהַבְתָּ לְרֵעֲךָ כָּמוֹךָ\", וַהֲרֵינִי אוֹהֵב כָּל אֶחָד מִבְּנֵי יִשְׂרָאֵל כְּנַפְשִׁי וּמְאוֹדִי, וַהֲרֵינִי מְזַמֵּן אֶת פִּי לְהִתְפַּלֵּל לִפְנֵי מֶלֶךְ מַלְכֵי הַמְּלָכִים, הַקָּדוֹשׁ בָּרוּךְ הוּא.","cond":[]},{"kind":"header","text":"פרשת העקדה","cond":[]},{"kind":"instruction","text":"פרשת העקדה","cond":[]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, זָכְרֵנוּ בְּזִכְרוֹן טוֹב מִלְּפָנֶיךָ, וּפָקְדֵנוּ בִּפְקוּדת יְשׁוּעָה וְרַחֲמִים מִשְּׁמֵי שְׁמֵי קֶדֶם, וּזְכָר לָנוּ יהוה אֱלֹהֵינוּ אַהֲבַת הַקַּדְמוֹנִים אַבְרָהָם יִצְחָק וְיִשְׂרָאֵל עֲבָדֶיךָ, אֶת הַבְּרִית וְאֶת הַחֶסֶד וְאֶת הַשְּׁבוּעָה שֶׁנִּשְׁבַּעְתָּ לְאַבְרָהָם אָבִינוּ בְּהַר הַמּוֹרִיָּה, וְאֶת הָעֲקֵדָה שֶׁעָקַד אֶת יִצְחָק בְּנוֹ עַל גַּבֵּי הַמִּזְבֵּחַ, כַּכָּתוּב בְּתוֹרָתָךְ:","cond":[]},{"kind":"text","text":"וַיְהִי אַחַר הַדְּבָרִים הָאֵלֶּה, וְהָאֱלֹהִים נִסָּה אֶת אַבְרָהָם, וַיֹּאמֶר אֵלָיו אַבְרָהָם, וַיֹּאמֶר הִנֵּנִי: וַיֹּאמֶר קַח נָא אֶת בִּנְךָ אֶת יְחִידְךָ אֲשֶׁר אָהַבְתָּ אֶת יִצְחָק, וְלֶךְ לְךָ אֶל אֶרֶץ הַמֹּרִיָּה, וְהַעֲלֵהוּ שָׁם לְעֹלָה עַל אַחַד הֶהָרִים אֲשֶׁר אֹמַר אֵלֶיךָ: וַיַּשְׁכֵּם אַבְרָהָם בַּבֹּקֶר וַיַּחֲבֹשׁ אֶת חֲמֹרוֹ, וַיִּקַּח אֶת שְׁנֵי נְעָרָיו אִתּוֹ וְאֵת יִצְחָק בְּנוֹ, וַיְבַקַּע עֲצֵי עֹלָה וַיָּקָם וַיֵּלֶךְ אֶל הַמָּקוֹם אֲשֶׁר אָמַר לוֹ הָאֱלֹהִים: בַּיּוֹם הַשְּׁלִישִׁי וַיִּשָּׂא אַבְרָהָם אֶת עֵינָיו, וַיַּרְא אֶת הַמָּקום מֵרָחוֹק: וַיֹּאמֶר אַבְרָהָם אֶל נְעָרָיו שְׁבוּ לָכֶם פֹּה עִם הַחֲמוֹר, וַאֲנִי וְהַנַּעַר נֵלְכָה עַד כֹּה, וְנִשְׁתַּחֲוֶה וְנָשׁוּבָה אֲלֵיכֶם: וַיִּקַּח אַבְרָהָם אֶת עֲצֵי הָעֹלָה וַיָּשֶׂם עַל יִצְחָק בְּנוֹ, וַיִּקַּח בְּיָדוֹ אֶת הָאֵשׁ וְאֶת הַמַּאֲכֶלֶת, וַיֵּלְכוּ שְׁנֵיהֶם יַחְדָּו: וַיֹּאמֶר יִצְחָק אֶל אַבְרָהָם אָבִיו וַיֹּאמֶר אָבִי, וַיֹּאמֶר הִנֶּנִּי בְנִי, וַיֹּאמֶר הִנֵּה הָאֵשׁ וְהָעֵצִים וְאַיֵּה הַשֶּׂה לְעֹלָה: וַיֹּאמֶר אַבְרָהָם: אֱלֹהִים יִרְאֶה לּוֹ הַשֶּׂה לְעֹלָה בְּנִי, וַיֵּלְכוּ שְׁנֵיהֶם יַחְדָּו: וַיָּבֹאוּ אֶל הַמָּקוֹם אֲשֶׁר אָמַר לוֹ הָאֱלֹהִים, וַיִּבֶן שָׁם אַבְרָהָם אֶת הַמִּזְבֵּחַ וַיַּעֲרֹךְ אֶת הָעֵצִים, וַיַּעֲקֹד אֶת יִצְחָק בְּנוֹ, וַיָּשֶׂם אֹתוֹ עַל הַמִּזְבֵּחַ מִמַּעַל לָעֵצִים: וַיִּשְׁלַח אַבְרָהָם אֶת יָדוֹ וַיִּקַּח אֶת הַמַּאֲכֶלֶת לִשְׁחֹט אֶת בְּנוֹ: וַיִּקְרָא אֵלָיו מַלְאַךְ יהוה מִן הַשָּׁמַיִם וַיֹּאמֶר אַבְרָהָם אַבְרָהָם, וַיֹּאמֶר הִנֵּנִי: וַיֹּאמֶר אַל תִּשְׁלַח יָדְךָ אֶל הַנַּעַר וְאַל תַּעַשׂ לוֹ מְאוּמָה, כִּי עַתָּה יָדַעְתִּי כִּי יְרֵא אֱלֹהִים אַתָּה וְלֹא חָשַׂכְתָּ אֶת בִּנְךָ אֶת יְחִידְךָ מִמֶּנִּי: וַיִּשָּׂא אַבְרָהָם אֶת עֵינָיו וַיַּרְא וְהִנֵּה אַיִל, אַחַר נֶאֱחַז בַּסְּבַךְ בְּקַרְנָיו, וַיֵּלֶךְ אַבְרָהָם וַיִּקַּח אֶת הָאַיִל, וַיַּעֲלֵהוּ לְעֹלָה תַּחַת בְּנוֹ: וַיִּקְרָא אַבְרָהָם שֵׁם הַמָּקוֹם הַהוּא יהוה יִרְאֶה, אֲשֶׁר יֵאָמֵר הַיּוֹם בְּהַר יהוה יֵרָאֶה: וַיִּקְרָא מַלְאַךְ יהוה אֶל אַבְרָהָם, שֵׁנִית מִן הַשָּׁמָיִם: וַיֹּאמֶר בִּי נִשְׁבַּעְתִּי נְאֻם יהוה, כִּי יַעַן אֲשֶׁר עָשִׂיתָ אֶת הַדָּבָר הַזֶּה וְלֹא חָשַׂכְתָּ אֶת בִּנְךָ אֶת יְחִידֶךָ: כִּי בָרֵךְ אֲבָרֶכְךָ וְהַרְבָּה אַרְבֶּה אֶת זַרְעֲךָ כְּכוֹכְבֵי הַשָּׁמַיִם וְכַחוֹל אֲשֶׁר עַל שְׂפַת הַיָּם, וְיִרַשׁ זַרְעֲךָ אֵת שַׁעַר אֹיְבָיו: וְהִתְבָּרְכוּ בְזַרְעֲךָ כֹּל גּוֹיֵי הָאָרֶץ, עֵקֶב אֲשֶׁר שָׁמַעְתָּ בְּקֹלִי: וַיָּשָׁב אַבְרָהָם אֶל נְעָרָיו וַיָּקֻמוּ וַיֵּלְכוּ יַחְדָּו אֶל בְּאֵר שָׁבַע, וַיֵּשֶׁב אַבְרָהָם בִּבְאֵר שָׁבַע:","cond":[]},{"kind":"text","text":"ושחט אתו על ירך המזבח צפנה לפני יהוה. וזרקו בני אהרן הכהנים את דמו על המזבח סביב:\n\nיהי רצון מלפניך יהוה אלהנו ואלהי אבותינו, שתתמלא רחמים עלינו. ובכן ברב רחמיך תזכר לנו עקדתו של יצחק אבינו בן אברהם אבינו עליו השלום, כאלו אפרו צבור ומנח על גבי המזבח, ותביט באפרו לרחם עלינו, ולבטל מעלינו כל גזרות קשות ורעות, ותזכנו לשוב בתשובה שלמה לפניך, ותצילנו מיצר הרע ומכל חטא ועון, ותאריך ימינו בטוב ושנותינו בנעימים:\n\nרִבּוֹנוֹ שֶׁל עוֹלָם, כְּמוֹ שֶׁכָּבַשׁ אַבְרָהָם אָבִינוּ אֶת רַחֲמָיו לַעֲשׂוֹת רְצוֹנְךָ בְּלֵבָב שָׁלֵם, כֵּן יִכְבְּשׁוּ רַחֲמֶיךָ אֶת כַּעֲסֶךָ, וְיִגֹּלּוּ רַחֲמֶיךָ עַל מִדּוֹתֶיךָ. וְתִתְנַהֵג עִמָּנוּ יהוה אֱלֹהֵינוּ בְּמִדַּת הַחֶסֶד וּבְמִדַּת הָרַחֲמִים, וְתִכָּנֵס לָנוּ לִפְנִים מִשּׁוּרַת הַדִּין, וּבְטוּבְךָ הַגָּדוֹל יָשׁוּב חֲרוֹן אַפָּךְ מֵעַמָּךְ וּמֵעִירָךְ וּמֵאַרְצָךְ וּמִנַּחֲלָתָךְ. וְקַיֶּם לָנוּ יהוה אֱלֹהֵינוּ אֶת הַדָּבָר שֶׁהִבְטַחְתָּנוּ בְּתוֹרָתָךְ עַל יְדֵי משֶׁה עַבְדָּךְ כָּאָמוּר: וְזָכַרְתִּי אֶת בְּרִיתִי יַעֲקוֹב, וְאַף אֶת בְּרִיתִי יִצְחָק, וְאַף אֶת בְּרִיתִי אַבְרָהָם אֶזְכֹּר וְהָאָרֶץ אֶזְכֹּר: וְנֶאֱמַר: וְאַף גַּם זֹאת בִּהְיוֹתָם בְּאֶרֶץ אֹיְבֵיהֶם, לֹא מְאַסְתִּים וְלֹא גְעַלְתִּים לְכַלּוֹתָם, לְהָפֵר בְּרִיתִי אִתָּם, כִּי אֲנִי יהוה אֱלֹהֵיהֶם: וְזָכַרְתִּי לָהֶם בְּרִית רִאשֹׁנִים, אֲשֶׁר הוֹצֵאתִי אֹתָם מֵאֶרֶץ מִצְרַיִם לְעֵינֵי הַגּוֹיִם, לִהְיוֹת לָהֶם לֵאֱלֹהִים, אֲנִי יהוה: וְנֶאֱמַר: וְשָׁב יהוה אֱלֹהֶיךָ אֶת שְׁבוּתְךָ וְרִחֲמֶךָ, וְשָׁב וְקִבֶּצְךָ מִכָּל הָעַמִּים אֲשֶׁר הֱפִיצְךָ יהוה אֱלֹהֶיךָ שָׁמָּה: אִם יִהְיֶה נִדַּחֲךָ בִּקְצֵה הַשָּׁמָיִם, מִשָּׁם יְקַבֶּצְךָ יהוה אֱלֹהֶיךָ וּמִשָּׁם יִקָּחֶךָ: וֶהֱבִיאֲךָ יהוה אֱלֹהֶיךָ אֶל הָאָרֶץ אֲשֶׁר יָרְשׁוּ אֲבוֹתֶיךָ וִירִשְׁתָּהּ, וְהֵיטִבְךָ וְהִרְבְּךָ מֵאֲבוֹתֶיךָ: וְנֶאֱמַר עַל יְדֵי נְבִיאֶיךָ: יהוה חָנֵּנוּ, לְךָ קִוִּינוּ, הֱיֵה זְרוֹעָם לַבְּקָרִים אַף יְשׁוּעָתֵנוּ בְּעֵת צָרָה: וְנֶאֱמַר: וְעֵת צָרָה הִיא לְיַעֲקֹב וּמִמֶּנָּה יִוָּשֵׁעַ: וְנֶאֱמַר: בְּכָל צָרָתָם לוֹ צָר וּמַלְאַךְ פָּנָיו הוֹשִׁיעָם, בְּאַהֲבָתוֹ וּבְחֶמְלָתוֹ הוּא גְאָלָם, וַיְנַטְּלֵם וַיְנַשְּׂאֵם כָּל יְמֵי עוֹלָם: וְנֶאֱמַר: מִי אֵל כָּמוֹךָ נֹשֵׂא עָוׂן וְעוֹבֵר עַל פֶּשַׁע לִשְׁאֵרִית נַחֲלָתוֹ, לֹא הֶחֱזִיק לָעַד אַפּוֹ, כִּי חָפֵץ חֶסֶד הוּא: יָשׁוּב יְרַחֲמֵנוּ יִכְבֹּשׁ עֲוׂנוֹתֵינוּ וְתַשְׁלִיךְ בִּמְצֻלוֹת יָם כָּל חַטֹּאתָם: תִּתֵּן אֱמֶת לְיַעֲקֹב, חֶסֶד לְאַבְרָהָם, אֲשֶׁר נִשְׁבַּעְתָּ לַאֲבוֹתֵינוּ מִימֵי קֶדֶם: וְנֶאֱמַר: וַהֲבִיאוֹתִים אֶל הַר קָדְשִׁי, וְשִׂמַּחְתִּים בְּבֵית תְּפִלָּתִי, עוֹלוֹתֵיהֶם וְזִבְחֵיהֶם לְרָצוֹן עַל מִזְבְּחִי, כִּי בֵיתִי בֵּית תְּפִלָּה יִקָּרֵא לְכָל הָעַמִּים:","cond":[]},{"kind":"header","text":"אלו דברים","cond":[]},{"kind":"text","text":"אֵלּוּ דְבָרִים שֶׁאֵין לָהֶם שִׁעוּר: הַפֵּאָה וְהַבִּכּוּרִים וְהָרֵאָיוֹן וּגְמִילוּת חֲסָדִים וְתַלְמוּד תּוֹרָה.\n\nאֵלּוּ דְבָרִים שֶׁאָדָם הָעוֹשֶׂה אוֹתָם אוֹכֵל מִפֵּרוֹתֵיהֶם בָּעוֹלָם הַזֶּה וְהַקֶּרֶן קַיֶּמֶת לוֹ לָעוֹלָם הַבָּא, וְאֵלּוּ הֵן: כִּבּוּד אָב וָאֵם, וּגְמִילוּת חֲסָדִים, וּבִקּוּר חוֹלִים, וְהַכְנָסַת אוֹרְחִים, וְהַשְׁכָּמַת בֵּית הַכְּנֶסֶת, וַהֲבָאַת שָׁלוֹם בֵּין אָדָם לַחֲבֵרוֹ וּבֵין אִישׁ לְאִשְׁתּוֹ, וְתַלְמוּד תּוֹרָה כְּנֶגֶד כֻּלָּם.\n\nלְעוֹלָם יְהֵא אָדָם יְרֵא שָׁמַיִם בַּסֵּתֶר כְּבַגָּלוּי וּמוֹדֶה עַל הָאֱמֶת, וְדוֹבֵר אֱמֶת בִּלְבָבוֹ וְיַשְׁכִּים וְיֹאמַר: רִבּוֹן הָעוֹלָמִים וַאֲדוֹנֵי הָאֲדוֹנִים, לא עַל צִדְקֹתֵינוּ אֲנַחְנוּ מַפִּילִים תַּחֲנוּנֵינוּ לְפָנֶיךָ כִּי עַל רַחֲמֶיךָ הָרַבִּים. אֲדֹנָי שְׁמָעָה, אֲדֹנָי סְלָחָה, אֲדֹנָי הַקְשִׁיבָה וַעֲשֵׂה אַל תְּאַחַר, לְמַעַנְךָ אֱלהַי, כִּי שִׁמְךָ נִקְרָא עַל עִירְךָ וְעַל עַמֶּךָ:\n\nמַה אֲנַחְנוּ מַה חַיֵּינוּ, מַה חַסְדֵּנוּ מַה צִּדְקוֹתֵינוּ, מַה כֹּחֵנוּ מַה גְּבוּרָתֵנוּ, מַה נֹּאמַר לְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, הֲלא כָּל הַגִּבּוֹרִים כְּאַיִן לְפָנֶיךָ, וְאַנְשֵׁי הַשֵּׁם כְּלֹא הָיוּ, וַחֲכָמִים כִּבְלִי מַדָּע וּנְבונִים כִּבְלִי הַשְׂכֵּל, כִּי כָל מַעֲשֵׂינוּ תֹהוּ וִימֵי חַיֵּינוּ הֶבֶל לְפָנֶיךָ, וּמוֹתַר הָאָדָם מִן הַבְּהֵמָה אָיִן כִּי הַכֹּל הָבֶל: לְבַד הַנְּשָׁמָה הַטְּהוֹרָה שֶׁהִיא עֲתִידָה לִתֵּן דִּין וְחֶשְׁבּוֹן לִפְנֵי כִסֵּא כְבוֹדֶךָ, וְכָל הַגּויִם כְּאַיִן נֶגְדֶּךָ, שֶׁנֶּאֱמַר: הֵן גּוֹיִם כְּמַר מִדְּלִי וּכְשַׁחַק מֹאזְנַיִם נֶחְשָׁבוּ, הֵן אִיִּים כַּדַּק יִטּוֹל: אֲבָל אֲנַחְנוּ עַמְּךָ בְּנֵי בְרִיתֶךָ, בְּנֵי אַבְרָהָם אֹהֲבֶךָ שֶׁנִּשְׁבַּעְתָּ לּוֹ בְּהַר הַמֹּרִיָּה, זֶרַע יִצְחָק עֲקֵדֶךָ שֶׁנֶּעֱקַד עַל גַּבֵּי הַמִּזְבֵּחַ, עֲדַת יַעֲקֹב בִּנְךָ בְכוֹרֶךָ, שֶׁמֵּאַהֲבָתְךָ שֶׁאָהַבְתָּ אוֹתוֹ וּמִשִּׂמְחָתְךָ שֶׁשָּׂמַחְתָּ בּוֹ קָרָאתָ אוֹתוֹ יִשְׂרָאֵל וִישֻׁרוּן. לְפִיכָךְ אֲנַחְנוּ חַיָּבִים לְהוֹדוֹת לָךְ וּלְשַׁבְּחָךְ וּלְפָאֲרָךְ וּלְרוֹמְמָךְ וְלִתֵּן שִׁיר שֶׁבַח וְהוֹדָאָה לְשִׁמְךָ הַגָּדוֹל וְחַיָּבִים אֲנַחְנוּ לוֹמַר לְפָנֶיךָ שִׁירָה בְּכָל יוֹם תָּמִיד. אַשְׁרֵנוּ מַה טּוֹב חֶלְקֵנוּ וּמַה נָּעִים גּוֹרָלֵנוּ, וּמַה יָפָה מְאֹד יְרֻשָּׁתֵנוּ. אַשְׁרֵנוּ כְּשֶׁאֲנַחְנוּ מַשְׁכִּימִים וּמַעֲרִיבִים בְּבָתֵּי כְנֵסִיּוֹת וּבְבָתֵּי מִדְרָשׁוֹת, וּמְיַחֲדִים שִׁמְךָ בְּכָל יוֹם תָּמִיד אוֹמְרִים פַּעֲמַיִם בְּאַהֲבָה:\nשְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:\nבלחש - בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד.\n\nאַתָּה הוּא אֶחָד קוֹדֶם שֶׁבָּרָאתָ הָעוֹלָם וְאַתָּה הוּא אֶחָד לְאַחַר שֶׁבָּרָאתָ הָעוֹלָם. אַתָּה הוּא אֵל בָּעוֹלָם הַזֶּה וְאַתָּה הוּא אֵל בָּעוֹלָם הַבָּא. וְאַתָּה הוּא, וּשְׁנותֶיךָ לא יִתָּמּוּ: קַדֵּשׁ שְׁמָךְ בְּעוֹלָמָךְ עַל עַם מְקַדְּשֵׁי שְׁמֶךָ, וּבִישׁוּעָתְךָ מַלְכֵּנוּ תָּרוּם וְתַגְבִּיהַּ קַרְנֵנוּ, וְתוֹשִׁיעֵנוּ בְקָרוב לְמַעַן שְׁמֶךָ. בָּרוּךְ הַמְקַדֵּשׁ שְׁמוֹ בָרַבִּים.\n\nאַתָּה הוּא יהוה הָאֱלֹהִים בַּשָּׁמַיִם מִמַּעַל וְעַל הָאָרֶץ מִתַּחַת בִּשְׁמֵי הַשָּׁמַיִם הָעֶלְיוֹנִים וְהַתַּחְתּוֹנִים. אַתָּה הוּא רִאשׁוֹן וְאַתָּה הוּא אַחֲרוֹן וּמִבַּלְעָדֶיךָ אֵין אֱלֹהִים, קַבֵּץ נְפוּצוֹת קֹוֶיךָ מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ, יַכִּירוּ וְיֵדְעוּ כָל בָּאֵי עוֹלָם כִּי אַתָּה הוּא הָאֱלֹהִים לְבַדְּךָ לְכֹל מַמְלְכוֹת הָאָרֶץ. אַתָּה עָשִׂיתָ אֶת הַשָּׁמַיִם וְאֶת הָאָרֶץ,\nאֶת הַיָּם וְאֶת כָּל אֲשֶׁר בָּם וּמִי בְכָל מַעֲשֵׂה יָדֶיךָ בָּעֶלְיונִים וּבַתַּחְתּונִים שֶׁיֹּאמַר לָךְ מַה תַּעֲשֶׂה וּמַה תִּפְעָל. אָבִינוּ שֶׁבַּשָּׁמַיִם חַי וְקַיָּם עֲשֵׂה עִמָּנוּ חֶסֶד בַּעֲבוּר כְּבוֹד שִׁמְךָ הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא שֶׁנִּקְרָא עָלֵינוּ וְקַיֵּם לָנוּ יהוה אֱלֹהֵינוּ אֶת הַדָּבָר שֶׁהִבְטַחְתָּנוּ עַל יְדֵי צְפַנְיָה חוזָךְ כָּאָמוּר: בָּעֵת הַהִיא אָבִיא אֶתְכֶם וּבָעֵת קַבְּצִי אֶתְכֶם, כִּי אֶתֵּן אֶתְכֶם לְשֵׁם וְלִתְהִלָּה בְּכֹל עַמֵּי הָאָרֶץ בְּשׁוּבִי אֶת שְׁבוּתֵיכֶם לְעֵינֵיכֶם אָמַר יהוה:","cond":[]},{"kind":"instruction","text":"פרשת הקורבנות","cond":[]},{"kind":"text","text":"יְהִי רָצון מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ שֶׁתְּרַחֵם עָלֵינוּ וְתִמְחוֹל לָנוּ אֶת כָּל חַטֹּאתֵינוּ, וּתְכַפֵּר לָנוּ אֶת כָּל עֲוׂנוֹתֵינוּ, וְתִמְחוֹל וְתִסְלַח לְכָל פְּשָׁעֵינוּ, וְשֶׁתִּבְנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵינוּ וְנַקְרִיב לְפָנֶיךָ קָרְבַּן הַתָּמִיד שֶׁיְּכַפֵּר בַּעֲדֵנוּ, כְּמו שֶׁכָּתַבְתָּ עָלֵינוּ בְתוֹרָתָךְ עַל יְדֵי מֹשֶׁה עַבְדָּךְ כָּאָמוּר: \n\nוַיְדַבֵּר יהוה אֶל מֹשֶׁה לֵּאמֹר: צַו אֶת בְּנֵי יִשרָאֵל וְאָמַרְתָּ אֲלֵהֶם, אֶת קָרְבָּנִי לַחְמִי לְאִשַּׁי, רֵיחַ נִיחֹחִי, תִּשְׁמְרוּ לְהַקְרִיב לִי בְּמוֹעֲדוֹ: וְאָמַרְתָּ לָהֶם, זֶה הָאִשֶּׁה אֲשֶׁר תַּקְרִיבוּ לַיהוה, כְּבָשִׂים בְּנֵי שָׁנָה תְמִימִים, שְׁנַיִם לַיּוֹם עֹלָה תָמִיד: אֶת הַכֶּבֶשׂ אֶחָד תַּעֲשֶׂה בַבֹּקֶר, וְאֵת הַכֶּבֶשׂ הַשֵּׁנִי תַּעֲשֶׂה בֵּין הָעַרְבָּיִם: וַעֲשִׂירִית הָאֵיפָה סֹלֶת לְמִנְחָה, בְּלוּלָה בְּשֶׁמֶן כָּתִית רְבִיעִת הַהִין: עֹלַת תָּמִיד, הָעֲשֻׂיָה בְּהַר סִינַי, לְרֵיחַ נִיחֹחַ אִשֶּׁה לַיהוה: וְנִסְכּוֹ רְבִיעִת הַהִין לַכֶּבֶשׂ הָאֶחָד, בַּקֹּדֶשׁ הַסֵּךְ נֶסֶךְ שֵׁכָר לַיהוה: וְאֵת הַכֶּבֶשׂ הַשֵּׁנִי תַּעֲשֶׂה בֵּין הָעַרְבָּיִם, כְּמִנְחַת הַבֹּקֶר וּכְנִסְכּוֹ תַּעֲשֶׂה, אִשֵּׁה רֵיחַ נִיחֹחַ לַיהוה:\n\nאַתָּה הוּא יהוה אֱלֹהֵינוּ שֶׁהִקְטִירוּ אֲבוֹתֵינוּ לְפָנֶיךָ אֶת קְטֹרֶת הַסַּמִּים בִּזְמַן שֶׁבֵּית הַמִּקְדָּשׁ קַיָּם, כַּאֲשֶׁר צִוִּיתָ אוֹתָם עַל יַד מֹשֶׁה נְבִיאָךְ, כַּכָּתוּב בְּתוֹרָתָךְ: וַיֹּאמֶר יהוה אֶל מֹשֶׁה, קַח לְךָ סַמִּים נָטָף וּשְׁחֵלֶת וְחֶלְבְּנָה סַמִּים וּלְבֹנָה זַכָּה בַּד בְּבַד יִהְיֶה: וְעָשִׂיתָ אֹתָהּ קְטֹרֶת, רֹקַח מַעֲשֶׂה רוֹקֵחַ, מְמֻלָּח טָהוֹר קֹדֶשׁ: וְשָׁחַקְתָּ מִמֶּנָּה הָדֵק, וְנָתַתָּה מִמֶּנָּה לִפְנֵי הָעֵדֻת בְּאֹהֶל מוֹעֵד אֲשֶׁר אִוָּעֵד לְךָ שָׁמָּה, קֹדֶשׁ קָדָשִׁים תִּהְיֶה לָכֶם:\n\nוְנֶאֱמַר: וְהִקְטִיר עָלָיו אַהֲרֹן קְטֹרֶת סַמִּים, בַּבֹּקֶר בַּבֹּקֶר בְּהֵיטִיבוֹ אֶת הַנֵּרוֹת יַקְטִירֶנָּה: וּבְהַעֲלֹת אַהֲרֹן אֶת הַנֵּרֹת בֵּין הָעַרְבַּיִם יַקְטִירֶנָּה, קְטֹרֶת תָּמִיד לִפְנֵי יהוה לְדֹרֹתֵיכֶם:\n\nתָּנוּ רַבָּנָן: פִּטּוּם הַקְּטֹרֶת כֵּיצַד? שְׁלֹשׁ מֵאוֹת וְשִׁשִּׁים וּשְׁמוֹנָה מָנִים הָיוּ בָהּ. שְׁלֹשׁ מֵאוֹת וְשִׁשִּׁים וַחֲמִשָּׁה כְּמִנְיַן יְמוֹת הַחַמָּה, מָנֶה לְכָל יוֹם, מַחֲצִיתוֹ בַּבֹּקֶר וּמַחֲצִיתו בָּעֶרֶב. וּשְׁלֹשָׁה מָנִים יְתֵרִים שֶׁמֵּהֶם מַכְנִיס כֹּהֵן גָּדוֹל וְנוֹטֵל מֵהֶם מְלֹא חָפְנָיו בְּיוֹם הַכִּפּוּרִים, וּמַחֲזִירָן לְמַכְתֶּשֶׁת בְּעֶרֶב יום הַכִּפּוּרִים כְּדֵי לְקַיֵּם מִצְוַת דַקָּה מִן הַדַּקָּה. וְאַחַד עָשר סַמָּנִים הָיוּ בָהּ, וְאֵלּוּ הֵן: (א) הַצֳּרִי (ב) וְהַצִּפֹּרֶן, (ג) וְהַחֶלְבְּנָה (ד) וְהַלְּבוֹנָה מִשְׁקַל שִׁבְעִים שִׁבְעִים מָנֶה, (ה) מֹר (ו) וּקְצִיעָה, (ז) וְשִׁבֹּלֶת נֵרְדְּ (ח) וְכַרְכֹּם מִשְׁקַל שִׁשָּׁה עָשָׂר שִׁשָּׁה עָשָׂר מָנֶה, (ט) קֹשְׁטְ שְׁנֵים עָשָׂר, (י) קִלּוּפָה שְׁלֹשָׁה, (יא) קִנָּמוֹן תִּשְׁעָה, בֹּרִית כַּרְשִׁינָא תִּשְׁעָה קַבִּין, יֵין קַפְרִיסִין סְאִין תְּלָת וְקַבִּין תְּלָתָא, וְאִם לֹא מָצָא יֵין קַפְרִיסִין מֵבִיא חֲמַר חִיוָר עַתִּיק. מֶלַח סְדוֹמִית רֹבַע, מַעֲלֶה עָשָׁן כָּל שֶׁהוּא. רִבִּי נָתָן הַבַּבְלִי אוֹמֵר: אַף כִּפַּת הַיַּרְדֵּן כָּל שֶׁהִיא. אִם נָתַן בָּהּ דְּבַשׁ פְּסָלָהּ, וְאִם חִסַּר אַחַת מִכָּל סַמְמָנֶיהָ חַיָּב מִיתָה.\n\nרַבָּן שִׁמְעוֹן בֶּן גַּמְלִיאֵל אוֹמֵר: הַצֳּרִי אֵינוֹ אֶלָּא שְׂרָף הַנּוֹטֵף מֵעֲצֵי הַקְּטָף. בֹּרִית כַּרְשִׁינָא לְמָה הִיא בָאָה? כְּדֵי לְשַׁפּות בָּהּ אֶת הַצִּפֹּרֶן כְּדֵי שֶׁתְּהֵא נָאָה. יֵין קַפְרִיסִין לְמָה הוּא בָא? כְּדֵי לִשְׁרוֹת בּוֹ אֶת הַצִּפֹּרֶן כְּדֵי שֶׁתְּהֵא עַזָּה. וַהֲלֹא מֵי רַגְלַיִם יָפִין לָהּ, אֶלָּא שֶׁאֵין מַכְנִיסִין מֵי רַגְלַיִם בַּמִּקְדָּשׁ מִפְּנֵי הַכָּבוֹד.\n\nתַּנְיָא: רִבִּי נָתָן אוֹמֵר: כְּשֶׁהוּא שׁוֹחֵק אוֹמֵר: הָדֵק הֵיטֵב, הֵיטֵב הָדֵק, מִפְּנֵי שֶׁהַקּוֹל יָפֶה לַבְּשָׂמִים. פִּטְּמָהּ לַחֲצָאִין כְּשֵׁרָה. לִשְׁלִישׁ וְלִרְבִיעַ לֹא שָׁמַעְנוּ. אָמַר רִבִּי יְהוּדָה: זֶה הַכְּלָל: אִם כְּמִדָּתָהּ כְּשֵׁרָה לַחֲצָאִין, וְאִם חִסַּר אַחַת מִכָּל סַמְמָנֶיהָ חַיָּב מִיתָה.\n\nתַּנֵי בַר קַפָּרָא: אַחַת לְשִׁשִּׁים אוֹ לְשִׁבְעִים שָׁנָה הָיְתָה בָאָה שֶׁל שִׁירַיִם לַחֲצָאִין. וְעוֹד תָּנֵי בַר קַפָּרָא: אִלּוּ הָיָה נוֹתֵן בָּהּ קוֹרְטוֹב שֶׁל דְּבַשׁ אֵין אָדָם יָכוֹל לַעֲמֹד מִפְּנֵי רֵיחָהּ, וְלָמָה אֵין מְעָרְבִין בָּהּ דְּבַשׁ? מִפְּנֵי שֶׁהַתּוֹרָה אָמְרָה: כִּי כָל שְׂאֹר וְכָל דְּבַשׁ לֹא תַקְטִירוּ מִמֶּנּוּ אִשֶּׁה לַיהוה:\n\nיהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה:\nיהוה צְבָאוֹת, אַשְׁרֵי אָדָם בּוֹטֵחַ בָּךְ:\nיהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:\nוְעָרְבָה לַיהוה מִנְחַת יְהוּדָה וִירוּשָׁלָיִם, כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמֹנִיּוֹת:\n\nאַבַּיֵּי הֲוָה מְסַדֵּר סֵדֶר הַמַּעֲרָכָה מִשְּׁמָא דִגְמָרָא וְאַלִּבָּא דְאַבָּא שָׁאוּל: מַעֲרָכָה גְדוֹלָה קוֹדֶמֶת לְמַעֲרָכָה שְׁנִיָּה שֶׁל קְטֹרֶת. וּמַעֲרָכָה שְׁנִיָּה שֶׁל קְטֹרֶת קוֹדֶמֶת לְסִדּוּר שְׁנֵי גְזִירֵי עֵצִים. וְסִדּוּר שְׁנֵי גְזִירֵי עֵצִים קוֹדֵם לְדִשּׁוּן מִזְבֵּחַ הַפְּנִימִי. וְדִשּׁוּן מִזְבֵּחַ הַפְּנִימִי קוֹדֵם לַהֲטָבַת חָמֵשׁ נֵרות. וַהֲטָבַת חָמֵשׁ נֵרוֹת קוֹדֶמֶת לְדַם הַתָּמִיד. וְדַם הַתָּמִיד קוֹדֵם לַהֲטָבַת שְׁתֵּי נֵרוֹת. וַהֲטָבַת שְׁתֵּי נֵרוֹת קוֹדֶמֶת לִקְטֹרֶת. וּקְטֹרֶת לְאֵבָרִים. וְאֵבָרִים לְמִנְחָה. וּמִנְחָה לַחֲבִתִּין. וַחֲבִתִּין לִנְסָכִין. וּנְסָכִין לְמוּסָפִין. וּמוּסָפִין לְבָזִיכִין. וּבָזִיכִין קוֹדְמִין לְתָמִיד שֶׁל בֵּין הָעַרְבָּיִם. שֶׁנֶּאֱמַר: וְעָרַךְ עָלֶיהָ הָעֹלָה, וְהִקְטִיר עָלֶיהָ חֶלְבֵי הַשְּׁלָמִים: עָלֶיהָ הַשְׁלֵם כָּל הַקָּרְבָּנוֹת כֻּלָּם.","cond":[]},{"kind":"text","text":"אָנָּא, בְּכֹחַ גְּדֻלַּת יְמִינְךָ, תַּתִּיר צְרוּרָה (אב\"ג ית\"ץ).","cond":[]},{"kind":"text","text":"קַבֵּל רִנַּת עַמְּךָ, שַׂגְּבֵנוּ, טַהֲרֵנוּ, נוֹרָא (קר\"ע שט\"ן).","cond":[]},{"kind":"text","text":"נָא גִּבּוֹר, דּוֹרְשֵׁי יִחוּדֶךָ, כְּבָבַת שָׁמְרֵם (נג\"ד יכ\"ש).","cond":[]},{"kind":"text","text":"בָּרְכֵם, טַהֲרֵם, רַחֲמֵי צִדְקָתְךָ תָּמִיד גָּמְלֵם (בט\"ר צת\"ג).","cond":[]},{"kind":"text","text":"חָסִין קָדוֹשׁ, בְּרֹב טוּבְךָ נַהֵל עֲדָתֶךָ (חק\"ב טנ\"ע).","cond":[]},{"kind":"text","text":"יָחִיד גֵּאֶה, לְעַמְּךָ פְנֵה, זוֹכְרֵי קְדֻשָּׁתֶךָ (יג\"ל פז\"ק).","cond":[]},{"kind":"text","text":"שַׁוְעָתֵנוּ קַבֵּל, וּשְׁמַע צַעֲקָתֵנוּ, יוֹדֵעַ תַּעֲלוּמוֹת (שק\"ו צי\"ת).","cond":[]},{"kind":"text","text":"ואומר - בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד.\n\nרִבּוֹן הָעוֹלָמִים, אַתָּה צִוִּיתָנוּ לְהַקְרִיב קָרְבַּן הַתָּמִיד בְּמוֹעֲדוֹ, וְלִהְיוֹת כֹּהֲנִים בַּעֲבוֹדָתָם וּלְוִיִּם בְּדוּכָנָם וְיִשְׂרָאֵל בְּמַעֲמָדָם, וְעַתָּה בַּעֲוׂנוֹתֵינוּ חָרֵב בֵּית הַמִּקְדָּשׁ וּבֻטַּל הַתָּמִיד וְאֵין לָנוּ לֹא כֹהֵן בַּעֲבוֹדָתוֹ, וְלֹא לֵוִי בְּדוּכָנוֹ, וְלֹא יִשְׂרָאֵל בְּמַעֲמָדוֹ, וְאַתָּה אָמַרְתָּ וּנְשַׁלְּמָה פָרִים שְׂפָתֵינוּ: לָכֵן יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ שֶׁיְּהֵא שִׂיחַ שִׂפְתוֹתֵינוּ זֶה חָשׁוּב וּמְקֻבָּל וּמְרוּצֶה לְפָנֶיךָ כְּאִלּוּ הִקְרַבְנוּ קָרְבַּן הַתָּמִיד בְּמוֹעֲדוֹ וְעָמַדְנוּ עַל מַעֲמָדוֹ, כְּמוֹ שֶׁנֶּאֱמַר: וּנְשַׁלְּמָה פָרִים שְׂפָתֵינוּ: וְנֶאֱמַר: וְשָׁחַט אוֹתוֹ עַל יֶרֶךְ הַמִּזְבֵּחַ צָפֹנָה לִפְנֵי יהוה: וְזָרְקוּ בְּנֵי אַהֲרֹן הַכֹּהֲנִים אֶת דָּמוֹ עַל הַמִּזְבֵּחַ סָבִיב: וְנֶאֱמַר: זאת הַתּוֹרָה לָעֹלָה לַמִּנְחָה וְלַחַטָּאת וְלָאָשָׁם, וְלַמִּלּוּאִים וּלְזֶבַח הַשְּׁלָמִים:","cond":[]},{"kind":"header","text":"איזהו מקומן","cond":[]},{"kind":"instruction","text":"פרק איזהו מקומן","cond":[]},{"kind":"text","text":"אֵיזֶהוּ מְקוֹמָן שֶׁל זְבָחִים: קָדְשֵׁי קָדָשִׁים שְׁחִיטָתָן בַּצָּפוֹן. פָּר וְשָׂעִיר שֶׁל יוֹם הַכִּפּוּרִים שְׁחִיטָתָן בַּצָּפוֹן, וְקִבּוּל דָּמָן בִּכְלִי שָׁרֵת בַּצָּפוֹן, וְדָמָן טָעוּן הַזָּיָה עַל בֵּין הַבַּדִּים וְעַל הַפָּרֹכֶת וְעַל מִזְבַּח הַזָּהָב, מַתָּנָה אַחַת מֵהֶן מְעַכָּבֶת. שְׁיָרֵי הַדָּם הָיָה שׁוֹפֵךְ עַל יְסוֹד מַעֲרָבִי שֶׁל מִזְבֵּחַ הַחִיצוֹן, אִם לֹא נָתַן לֹא עִכֵּב.\n\nפָּרִים הַנִּשְׂרָפִים וּשְׂעִירִים הַנִּשְׂרָפִים שְׁחִיטָתָן בַּצָּפוֹן, וְקִבּוּל דָּמָן בִּכְלִי שָׁרֵת בַּצָּפוֹן, וְדָמָן טָעוּן הַזָּיָה עַל הַפָּרֹכֶת וְעַל מִזְבַּח הַזָּהָב, מַתָּנָה אַחַת מֵהֶן מְעַכָּבֶת. שְׁיָרֵי הַדָּם הָיָה שׁוֹפֵךְ עַל יְסוֹד מַעֲרָבִי שֶׁל מִזְבֵּחַ הַחִיצוֹן, אִם לֹא נָתַן לֹא עִכֵּב. אֵלּוּ וָאֵלּוּ נִשְׂרָפִין בְּבֵית הַדָּשֶׁן.\n\nחַטֹּאת הַצִּבּוּר וְהַיָּחִיד, אֵלּוּ הֵן חַטֹּאת הַצִּבּוּר: שְׂעִירֵי רָאשֵׁי חֳדָשִׁים וְשֶׁל מוֹעֲדוֹת, שְׁחִיטָתָן בַּצָּפוֹן, וְקִבּוּל דָּמָן בִּכְלִי שָׁרֵת בַּצָּפוֹן, וְדָמָן טָעוּן אַרְבַּע מַתָּנוֹת עַל אַרְבַּע קְרָנוֹת. כֵּיצַד? עָלָה בַכֶּבֶשׁ, וּפָנָה לַסּוֹבֵב, וּבָא לוֹ לְקֶרֶן דְּרוֹמִית מִזְרָחִית, מִזְרָחִית צְפוֹנִית, צְפוֹנִית מַעֲרָבִית, מַעֲרָבִית דְּרוֹמִית. שְׁיָרֵי הַדָּם הָיָה שׁוֹפֵךְ עַל יְסוֹד דְּרוֹמִי, וְנֶאֱכָלִין לִפְנִים מִן הַקְּלָעִים, לְזִכְרֵי כְהֻנָּה, בְּכָל מַאֲכָל, לְיוֹם וָלַיְלָה עַד חֲצוֹת.\n\nהָעוֹלָה קֹדֶשׁ קָדָשִׁים, שְׁחִיטָתָהּ בַּצָּפוֹן, וְקִבּוּל דָּמָהּ בִּכְלִי שָׁרֵת בַּצָּפוֹן, וְדָמָהּ טָעוּן שְׁתֵּי מַתָּנוֹת שֶׁהֵן אַרְבַּע, וּטְעוּנָה הֶפְשֵׁט וְנִתּוּחַ וְכָלִיל לָאִשִּׁים.\n\nזִבְחֵי שַׁלְמֵי צִבּוּר וַאֲשָׁמוֹת, אֵלּוּ הֵן אֲשָׁמוֹת: אֲשַׁם גְּזֵלוֹת, אֲשַׁם מְעִילוֹת, אֲשַׁם שִׁפְחָה חֲרוּפָה, אֲשַׁם נָזִיר, אֲשַׁם מְצֹרָע, אָשָׁם תָּלוּי, שְׁחִיטָתָן בַּצָּפוֹן, וְקִבּוּל דָּמָן בִּכְלִי שָׁרֵת בַּצָּפוֹן, וְדָמָן טָעוּן שְׁתֵּי מַתָּנוֹת שֶׁהֵן אַרְבַּע, וְנֶאֱכָלִין לִפְנִים מִן הַקְּלָעִים, לְזִכְרֵי כְהֻנָּה, בְּכָל מַאֲכָל, לְיוֹם וָלַיְלָה עַד חֲצוֹת.\n\nהַתּוֹדָה וְאֵיל נָזִיר קָדָשִׁים קַלִּים, שְׁחִיטָתָן בְּכָל מָקוֹם בָּעֲזָרָה, וְדָמָן טָעוּן שְׁתֵּי מַתָּנוֹת שֶׁהֵן אַרְבַּע, וְנֶאֱכָלִין בְּכָל הָעִיר, לְכָל אָדָם, בְּכָל מַאֲכָל, לְיוֹם וָלַיְלָה עַד חֲצוֹת. הַמּוּרָם מֵהֶם כַּיּוֹצֵא בָהֶם, אֶלָּא שֶׁהַמּוּרָם נֶאֱכָל לַכֹּהֲנִים לִנְשֵׁיהֶם וְלִבְנֵיהֶם וּלְעַבְדֵיהֶם.\n\nשְׁלָמִים קָדָשִׁים קַלִּים, שְׁחִיטָתָן בְּכָל מָקום בָּעֲזָרָה, וְדָמָן טָעוּן שְׁתֵּי מַתָּנוֹת שֶׁהֵן אַרְבַּע, וְנֶאֱכָלִין בְּכָל הָעִיר, לְכָל אָדָם, בְּכָל מַאֲכָל, לִשְׁנֵי יָמִים וְלַיְלָה אֶחָד. הַמּוּרָם מֵהֶם כַּיּוֹצֵא בָהֶם, אֶלָּא שֶׁהַמּוּרָם נֶאֱכָל לַכֹּהֲנִים לִנְשֵׁיהֶם וְלִבְנֵיהֶם וּלְעַבְדֵיהֶם.\n\nהַבְּכוֹר וְהַמַּעֲשֵׂר וְהַפֶּסַח קָדָשִׁים קַלִּים, שְׁחִיטָתָן בְּכָל מָקוֹם בָּעֲזָרָה, וְדָמָן טָעוּן מַתָּנָה אֶחָת, וּבִלְבָד שֶׁיִּתֵּן כְּנֶגֶד הַיְסוֹד. שִׁנָּה בַאֲכִילָתָן: הַבְּכוֹר נֶאֱכָל לַכֹּהֲנִים, וְהַמַּעֲשֵׂר לְכָל אָדָם. וְנֶאֱכָלִין בְּכָל הָעִיר, בְּכָל מַאֲכָל, לִשְׁנֵי יָמִים וְלַיְלָה אֶחָד. הַפֶּסַח אֵינוֹ נֶאֱכָל אֶלָּא בַלַּיְלָה, וְאֵינוֹ נֶאֱכָל אֶלָּא עַד חֲצוֹת, וְאֵינוֹ נֶאֱכָל אֶלָּא לִמְנוּיָיו, וְאֵינוֹ נֶאֱכָל אֶלָּא צָלִי.","cond":[]},{"kind":"header","text":"רבי ישמעאל אומר","cond":[]},{"kind":"instruction","text":"ברייתא דרבי ישמעאל","cond":[]},{"kind":"text","text":"רִבִּי יִשְׁמָעֵאל אוֹמֵר: בִּשְׁלשׁ עֶשְׂרֵה מִדּוֹת הַתּוֹרָה נִדְרֶשֶׁת: מִקַּל וָחֹמֶר, מִגְּזֵרָה שָׁוֶה, מִבִּנְיַן אָב וְכָתוּב אֶחָד וּמִבִּנְיַן אָב וּשְׁנֵי כְתוּבִים, מִכְּלַל וּפְרָט, מִפְּרָט וּכְלָל, כְּלָל וּפְרָט וּכְלָל אִי אַתָּה דָן אֶלָּא כְּעֵין הַפְּרָט, מִכְּלַל שֶׁהוּא צָרִיךְ לִפְרָט, וּמִפְּרָט שֶׁהוּא צָרִיךְ לִכְלַל, וְכָל דָּבָר שֶׁהָיָה בִכְלָל וְיָצָא מִן הַכְּלָל לְלַמֵּד, לֹא לְלַמֵּד עַל עַצְמוֹ יָצָא, אֶלָּא לְלַמֵּד עַל הַכְּלָל כֻּלּוֹ יָצָא, וְכָל דָּבָר שֶׁהָיָה בִכְלָל וְיָצָא לִטְעוֹן טֹעַן אַחַר שֶׁהוּא כְעִנְיָנוֹ יָצָא לְהָקֵל וְלֹא לְהַחְמִיר, וְכָל דָּבָר שֶׁהָיָה בִּכְלָל וְיָצָא לִטְעון טֹעַן אַחַר שֶׁלֹּא כְעִנְיָנוֹ יָצָא לְהָקֵל וּלְהַחְמִיר, וְכָל דָּבָר שֶׁהָיָה בִּכְלָל וְיָצָא לִדּוֹן בְּדְבָר חָדָשׁ אִי אַתָּה יָכוֹל לְהַחֲזִירוֹ לִכְלָלוֹ עַד שֶׁיַּחֲזִירֶנּוּ הַכָּתוּב לִכְלָלוֹ בְפֵירוּשׁ, וְדָבָר הַלָּמֵד מֵעִנְיָנוֹ וְדָבָר הַלָּמֵד מִסּוֹפוֹ, וְכַן שְׁנֵי כְתוּבִים הַמַּכְחִישִׁים זֶה אֶת זֶה עַד שֶׁיָּבֹא הַכָּתוּב הַשְּׁלִישִׁי וְיַכְרִיעַ בֵּינֵיהֶם.\n\nיְהוּדָה בֶּן תֵּימָא אוֹמֵר: הֱוֵי עַז כַּנָּמֵר, וְקַל כַּנֶּשֶׁר, וְרָץ כַּצְּבִי, וְגִבּוֹר כַּאֲרִי לַעֲשׂוֹת רָצוֹן אָבִיךָ שֶׁבַּשָּׁמַיִם. הוּא הָיָה אוֹמֵר: עַז פָּנִים לַגֵּיהִנָּם, וּבוֹש פָּנִים לְגַן עֵדֶן.\n\nיְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּבְנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵינוּ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתָךְ, לַעֲשׂוֹת חֻקֵּי רְצוֹנָךְ, וּלְעָבְדָךְ בְּלֵבָב שָׁלֵם.","cond":[]},{"kind":"instruction","text":"קדיש על ישראל","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.\nעַל יִשְׂרָאֵל וְעַל רַבָּנָן וְעַל תַּלְמִידֵיהוֹן וְעַל כָּל תַּלְמִידֵי תַלְמִידֵיהוֹן, דְּעָסְקִין בְּאוֹרַיְתָא קַדִּישְׁתָּא, דִּי בְאַתְרָא הָדֵין וְדִי בְכָל אֲתַר וַאֲתַר, יְהֵא לָנָא וּלְכוֹן וּלְהוֹן, חִנָּא וְחִסְדָּא וְרַחֲמֵי, מִן קֳדָם אֱלָהָא מָארֵי שְׁמַיָּא וְאַרְעָא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא, חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה וְשֵיזָבָא וּרְפוּאָה וּגְאֻלָּה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה, לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"header","text":"פסוקי דזמרה","cond":[]},{"kind":"instruction","text":"פסוקי דזמרה \n\nמזמורי תהילים בפסוקי דזמרה","cond":[]},{"kind":"text","text":"הוֹדוּ לַיהוה קִרְאוֹ בִשְׁמוֹ, הוֹדִיעוּ בָעַמִּים עֲלִילוֹתָיו: שִׁירוּ לוֹ זַמְּרוּ לוֹ, שִׂיחוּ בְּכָל נִפְלְאוֹתָיו: הִתְהַלְלוּ בְּשֵׁם קָדְשׁוֹ, יִשְׂמַח לֵב מְבַקְשֵׁי יהוה: דִּרְשׁוּ יהוה וְעֻזּוֹ, בַּקְּשׁוּ פָנָיו תָּמִיד: זִכְרוּ נִפְלְאוֹתָיו אֲשֶׁר עָשָׂה, מֹפְתָיו וּמִשְׁפְּטֵי פִיהוּ: זֶרַע יִשְׂרָאֵל עַבְדּוֹ, בְּנֵי יַעֲקֹב בְּחִירָיו: הוּא יהוה אֱלֹהֵינוּ בְּכָל הָאָרֶץ מִשְׁפָּטָיו: זִכְרוּ לְעוֹלָם בְּרִיתוֹ, דָּבָר צִוָּה לְאֶלֶף דּוֹר: אֲשֶׁר כָּרַת אֶת אַבְרָהָם, וּשְׁבוּעָתוֹ לְיִצְחָק: וַיַּעֲמִידֶהָ לְיַעֲקֹב לְחֹק, לְיִשְׂרָאֵל בְּרִית עוֹלָם: לֵאמֹר, לְךָ אֶתֵּן אֶרֶץ כְּנָעַן, חֶבֶל נַחֲלַתְכֶם: בִּהְיוֹתְכֶם מְתֵי מִסְפָּר, כִּמְעַט וְגָרִים בָּהּ: וַיִּתְהַלְּכוּ מִגּוֹי אֶל גּוֹי וּמִמַּמְלָכָה אֶל עַם אַחֵר: לֹא הִנִּיחַ לְאִישׁ לְעָשְׁקָם, וַיּוֹכַח עֲלֵיהֶם מְלָכִים: אַל תִּגְּעוּ בִּמְשִׁיחָי, וּבִנְבִיאַי אַל תָּרֵעוּ: שִׁירוּ לַיהוה כָּל הָאָרֶץ, בַּשְּׂרוּ מִיּוֹם אֶל יוֹם יְשׁוּעָתוֹ: סַפְּרוּ בַגּוֹיִם אֶת כְּבוֹדוֹ, בְּכָל הָעַמִּים נִפְלְאֹתָיו: כִּי גָדוֹל יהוה וּמְהֻלָּל מְאֹד, וְנוֹרָא הוּא עַל כָּל אֱלֹהִים: כִּי כָּל אֱלֹהֵי הָעַמִּים אֱלִילִים, וַיהוה שָׁמַיִם עָשָׂה: הוֹד וְהָדָר לְפָנָיו, עֹז וְחֶדְוָה בִּמְקֹמוֹ: הָבוּ לַיהוה מִשְׁפְּחוֹת עַמִּים, הָבוּ לַיהוה כָּבוֹד וָעֹז: הָבוּ לַיהוה כְּבוֹד שְׁמוֹ, שְׂאוּ מִנְחָה וּבֹאוּ לְפָנָיו, הִשְׁתַּחֲווּ לַיהוה בְּהַדְרַת קֹדֶשׁ: חִילוּ מִלְּפָנָיו כָּל הָאָרֶץ, אַף תִּכּוֹן תֵּבֵל בַּל תִּמּוֹט: יִשְׂמְחוּ הַשָּׁמַיִם וְתָגֵל הָאָרֶץ, וְיֹאמְרוּ בַגּוֹיִם יהוה מָלָךְ: יִרְעַם הַיָּם וּמְלוֹאוֹ, יַעֲלֹץ הַשָּׂדֶה וְכָל אֲשֶׁר בּוֹ: אָז יְרַנְּנוּ עֲצֵי הַיָּעַר מִלִּפְנֵי יהוה, כִּי בָא לִשְׁפּוֹט אֶת הָאָרֶץ: הוֹדוּ לַיהוה כִּי טוֹב, כִּי לְעוֹלָם חַסְדּוֹ: וְאִמְרוּ, הוֹשִׁיעֵנוּ אֱלֹהֵי יִשְׁעֵנוּ וְקַבְּצֵנוּ וְהַצִּילֵנוּ מִן הַגּוֹיִם, לְהֹדוֹת לְשֵׁם קָדְשֶׁךָ, לְהִשְׁתַּבֵּחַ בִּתְהִלָּתֶךָ: בָּרוּךְ יהוה אֱלֹהֵי יִשְׂרָאֵל מִן הָעוֹלָם וְעַד הָעֹלָם, וַיֹּאמְרוּ כָל הָעָם אָמֵן וְהַלֵּל לַיהוה: רוֹמְמוּ יהוה אֱלֹהֵינוּ וְהִשְׁתַּחֲווּ לַהֲדֹם רַגְלָיו, קָדוֹשׁ הוּא: רוֹמְמוּ יהוה אֱלֹהֵינוּ וְהִשְׁתַּחֲווּ לְהַר קָדְשׁוֹ, כִּי קָדוֹשׁ יהוה אֱלֹהֵינוּ: וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית, וְהִרְבָּה לְהָשִׁיב אַפּוֹ וְלֹא יָעִיר כָּל חֲמָתוֹ: אַתָּה יהוה לֹא תִכְלָא רַחֲמֶיךָ מִמֶּנִּי, חַסְדְּךָ וַאֲמִתְּךָ תָּמִיד יִצְּרוּנִי: זְכֹר רַחֲמֶיךָ יהוה, וַחֲסָדֶיךָ, כִּי מֵעוֹלָם הֵמָּה: תְּנוּ עֹז לֵאלֹהִים, עַל יִשְׂרָאֵל גַּאֲוָתוֹ וְעֻזּוֹ בַּשְּׁחָקִים: נוֹרָא אֱלֹהִים מִמִּקְדָּשֶׁיךָ אֵל יִשְׂרָאֵל, הוּא נֹתֵן עֹז וְתַעֲצֻמוֹת לָעָם, בָּרוּךְ אֱלֹהִים: אֵל נְקָמוֹת יהוה, אֵל נְקָמוֹת הוֹפִיעַ: הִנָּשֵׂא שֹׁפֵט הָאָרֶץ, הָשֵׁב גְּמוּל עַל גֵּאִים: לַיהוה הַיְשׁוּעָה עַל עַמְּךָ בִרְכָתֶךָ, סֶּלָה: יהוה צְבָאוֹת עִמָּנוּ מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב, סֶלָה: יהוה צְבָאוֹת אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ: הוֹשִׁיעָה אֶת עַמֶּךָ וּבָרֵךְ אֶת נַחֲלָתֶךָ, וּרְעֵם וְנַשְּׂאֵם עַד הָעוֹלָם: נַפְשֵׁנוּ חִכְּתָה לַיהוה, עֶזְרֵנוּ וּמָגִנֵּנוּ הוּא: כִּי בוֹ יִשְׂמַח לִבֵּנוּ כִּי בְשֵׁם קָדְשׁוֹ בָטָחְנוּ: יְהִי חַסְדְּךָ יהוה עָלֵינוּ כַּאֲשֶׁר יִחַלְנוּ לָךְ: הַרְאֵנוּ יהוה חַסְדֶּךָ, וְיֶשְׁעֲךָ תִּתֶּן לָנוּ: קוּמָה עֶזְרָתָה לָּנוּ וּפְדֵנוּ לְמַעַן חַסְדֶּךָ: אָנֹכִי יהוה אֱלֹהֶיךָ הַמַּעַלְךָ מֵאֶרֶץ מִצְרָיִם, הַרְחֶב פִּיךָ וַאֲמַלְאֵהוּ: אַשְׁרֵי הָעָם שֶׁכָּכָה לוֹ, אַשְׁרֵי הָעָם שֶׁיהוה אֱלֹהָיו: וַאֲנִי בְּחַסְדְּךָ בָטַחְתִּי, יָגֵל לִבִּי בִּישׁוּעָתֶךָ, אָשִׁירָה לַיהוה כִּי גָמַל עָלָי (ס\"ת יל\"י):","cond":[]},{"kind":"instruction","text":"גם בחנוכה יתחיל \"ארוממך\" ולא יתחיל \"מזמור שיר חנוכת\".","cond":[]},{"kind":"text","text":"אֲרוֹמִמְךָ יהוה כִּי דִלִּיתָנִי, וְלֹא שִׂמַּחְתָּ אֹיְבַי לִי: יהוה אֱלֹהָי שִׁוַּעְתִּי אֵלֶיךָ וַתִּרְפָּאֵנִי: יהוה, הֶעֱלִיתָ מִן שְׁאוֹל נַפְשִׁי, חִיִּיתַנִי מִיָּרְדִי בוֹר: זַמְּרוּ לַיהוה חֲסִידָיו וְהוֹדוּ לְזֵכֶר קָדְשׁוֹ: כִּי רֶגַע בְּאַפּוֹ חַיִּים בִּרְצוֹנוֹ, בָּעֶרֶב יָלִין בֶּכִי וְלַבֹּקֶר רִנָּה: וַאֲנִי אָמַרְתִּי בְשַׁלְוִי בַּל אֶמּוֹט לְעוֹלָם: יהוה בִּרְצוֹנְךָ הֶעֱמַדְתָּה לְהַרְרִי עֹז, הִסְתַּרְתָּ פָנֶיךָ הָיִיתִי נִבְהָל: אֵלֶיךָ יהוה אֶקְרָא וְאֶל אֲדֹנָי אֶתְחַנָּן: מַה בֶּצַע בְּדָמִי בְּרִדְתִּי אֶל שָׁחַת, הֲיוֹדְךָ עָפָר הֲיַגִּיד אֲמִתֶּךָ: שְׁמַע יהוה וְחָנֵּנִי, יהוה הֱיֵה עֹזֵר לִי: הָפַכְתָּ מִסְפְּדִי לְמָחוֹל לִי, פִּתַּחְתָּ שַׂקִּי וַתְּאַזְּרֵנִי שִׂמְחָה: לְמַעַן יְזַמֶּרְךָ כָבוֹד וְלֹא יִדֹּם, יהוה אֱלֹהַי לְעוֹלָם אוֹדֶךָּ:","cond":[]},{"kind":"special","text":"יהוה הוּא הָאֱלֹהִים, יהוה הוּא הָאֱלֹהִים:\nיהוה הוּא הָאֱלֹהִים, יהוה הוּא הָאֱלֹהִים:","cond":["ayt"]},{"kind":"special","text":"יהוה הוּא הָאֱלֹהִים, יהוה הוּא הָאֱלֹהִים:\nיהוה הוּא הָאֱלֹהִים, יהוה הוּא הָאֱלֹהִים:","cond":["hoshanaRaba"]},{"kind":"text","text":"יהוה מֶלֶךְ, יהוה מָלָךְ, יהוה יִמְלֹך לְעֹלָם וָעֵד.\nיהוה מֶלֶךְ, יהוה מָלָךְ, יהוה יִמְלֹך לְעֹלָם וָעֵד.\nוְהָיָה יהוה לְמֶלֶךְ עַל כָּל הָאָרֶץ, בַּיּוֹם הַהוּא יִהְיֶה יהוה אֶחָד וּשְׁמוֹ אֶחָד:\n\nהוֹשִׁיעֵנוּ יהוה אֱלֹהֵינוּ וְקַבְּצֵנוּ מִן הַגּוֹיִם, לְהוֹדוֹת לְשֵׁם קָדְשֶׁךָ לְהִשְׁתַּבֵּחַ בִּתְהִלָּתֶךָ: בָּרוּךְ יהוה אֱלֹהֵי יִשְׂרָאֵל מִן הָעוֹלָם וְעַד הָעוֹלָם, וְאָמַר כָּל הָעָם אָמֵן, הַלְלוּיָהּ: כֹּל הַנְּשָׁמָה תְּהַלֵּל יָהּ, הַלְלוּיָהּ:\nכִּי עִמְּךָ מְקוֹר חַיִּים, בְּאוֹרְךָ נִרְאֶה אוֹר: שִׁוִּיתִי יהוה לְנֶגְדִּי תָמִיד, כִּי מִימִינִי בַּל אֶמּוֹט:","cond":[]},{"kind":"text","text":"לַמְנַצֵּחַ מִזְמוֹר לְדָוִד: הַשָּׁמַיִם מְסַפְּרִים כְּבוֹד אֵל, וּמַעֲשה יָדָיו מַגִּיד הָרָקִיעַ: יוֹם לְיוֹם יַבִּיעַ אֹמֶר, וְלַיְלָה לְלַיְלָה יְחַוֶּה דָּעַת: אֵין אֹמֶר וְאֵין דְּבָרִים, בְּלִי נִשְׁמָע קוֹלָם: בְּכָל הָאָרֶץ יָצָא קַוָּם, וּבִקְצֵה תֵבֵל מִלֵּיהֶם, לַשֶּׁמֶשׁ שָׂם אֹהֶל בָּהֶם: וְהוּא כְּחָתָן יֹצֵא מֵחֻפָּתוֹ, יָשִׂישׂ כְּגִבּוֹר לָרוּץ אֹרַח: מִקְצֵה הַשָּׁמַיִם מוֹצָאוֹ וּתְקוּפָתוֹ עַל קְצוֹתָם, וְאֵין נִסְתָּר מֵחַמָּתוֹ: תּוֹרַת יהוה תְּמִימָה מְשִׁיבַת נָפֶשׁ, עֵדוּת יהוה נֶאֱמָנָה מַחְכִּימַת פֶּתִי: פִּקּוּדֵי יהוה יְשָׁרִים מְשַׂמְּחֵי לֵב, מִצְוַת יהוה בָּרָה מְאִירַת עֵינָיִם: יִרְאַת יהוה טְהוֹרָה עומֶדֶת לָעַד, מִשְׁפְּטֵי יהוה אֱמֶת צָדְקוּ יַחְדָּו: הַנֶחֱמָדִים מִזָּהָב וּמִפָּז רָב, וּמְתוּקִים מִדְּבַשׁ וְנֹפֶת צוּפִים: גַּם עַבְדְּךָ נִזְהָר בָּהֶם, בְּשָׁמְרָם עֵקֶב רָב: שְׁגִיאות מִי יָבִין מִנִּסְתָּרוֹת נַקֵּנִי: גַּם מִזֵּדִים חֲשֹׂךְ עַבְדֶּךָ, אַל יִמְשְׁלוּ בִי אָז אֵיתָם, וְנִקֵּיתִי מִפֶּשַׁע רָב: יִהְיוּ לְרָצון אִמְרֵי פִי וְהֶגְיון לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגֹאֲלִי:\n\nרַנְּנוּ צַדִּיקִים בַּיהוה, לַיְשָׁרִים נָאוָה תְהִלָּה: הוֹדוּ לַיהוה בְּכִנּוֹר, בְּנֵבֶל עָשׂוֹר זַמְּרוּ לוֹ: שִׁירוּ לוֹ שִׁיר חָדָשׁ, הֵיטִיבוּ נַגֵּן בִּתְרוּעָה: כִּי יָשָׁר דְּבַר יהוה, וְכָל מַעֲשֵׂהוּ בֶּאֱמוּנָה: אֹהֵב צְדָקָה וּמִשְׁפָּט, חֶסֶד יהוה מָלְאָה הָאָרֶץ: בִּדְבַר יהוה שָׁמַיִם נַעֲשׂוּ, וּבְרוּחַ פִּיו כָּל צְבָאָם: כֹּנֵס כַּנֵּד מֵי הַיָּם, נֹתֵן בְּאוֹצָרוֹת תְּהוֹמוֹת: יִירְאוּ מֵיהוה כָּל הָאָרֶץ, מִמֶּנּוּ יָגוּרוּ כָּל יֹשְׁבֵי תֵבֵל: כִּי הוּא אָמַר וַיֶּהִי, הוּא צִוָּה וַיַּעֲמֹד: יהוה הֵפִיר עֲצַת גּוֹיִם, הֵנִיא מַחְשְׁבוֹת עַמִּים: עֲצַת יהוה לְעוֹלָם תַּעֲמֹד, מַחְשְׁבוֹת לִבּוֹ לְדֹר וָדֹר: אַשְׁרֵי הַגּוֹי אֲשֶׁר יהוה אֱלֹהָיו, הָעָם בָּחַר לְנַחֲלָה לוֹ: מִשָּׁמַיִם הִבִּיט יהוה, רָאָה אֶת כָּל בְּנֵי הָאָדָם: מִמְּכוֹן שִׁבְתּוֹ הִשְׁגִּיחַ אֶל כָּל יֹשְׁבֵי הָאָרֶץ: הַיּוֹצֵר יַחַד לִבָּם, הַמֵּבִין אֶל כָּל מַעֲשֵׂיהֶם: אֵין הַמֶּלֶךְ נוֹשָׁע בְּרָב חָיִל, גִּבּוֹר לא יִנָּצֵל בְּרָב כֹּחַ: שֶׁקֶר הַסּוּס לִתְשׁוּעָה, וּבְרֹב חֵילוֹ לֹא יְמַלֵּט: הִנֵּה עֵין יהוה אֶל יְרֵאָיו, לַמְיַחֲלִים לְחַסְדּוֹ: לְהַצִּיל מִמָּוֶת נַפְשָׁם, וּלְחַיּוֹתָם בָּרָעָב: נַפְשֵׁנוּ חִכְּתָה לַיהוה, עֶזְרֵנוּ וּמָגִנֵּנוּ הוּא: כִּי בוֹ יִשְׂמַח לִבֵּנוּ, כִּי בְשֵׁם קָדְשׁו בָטָחְנוּ: יְהִי חַסְדְּךָ יהוה עָלֵינוּ, כַּאֲשֶׁר יִחַלְנוּ לָךְ:\n\nלְדָוִד בְּשַׁנּוֹתו אֶת טַעְמוֹ לִפְנֵי אֲבִימֶלֶךְ, וַיְגָרְשֵׁהוּ וַיֵּלַךְ: אֲבָרְכָה אֶת יהוה בְּכָל עֵת, תָּמִיד תְּהִלָּתוֹ בְּפִי: בַּיהוה תִּתְהַלֵּל נַפְשִׁי, יִשְׁמְעוּ עֲנָוִים וְיִשמָחוּ: גַדְּלוּ לַיהוה אִתִּי, וּנְרוֹמְמָה שְׁמוֹ יַחְדָּו: דָּרַשְׁתִּי אֶת יהוה וְעָנָנִי, וּמִכָּל מְגוּרוֹתַי הִצִּילָנִי: הִבִּיטוּ אֵלָיו וְנָהָרוּ, וּפְנֵיהֶם אַל יֶחְפָּרוּ: זֶה עָנִי קָרָא וַיהוה שָׁמֵעַ, וּמִכָּל צָרוֹתָיו הוֹשִׁיעוֹ: חוֹנֶה מַלְאַךְ יהוה סָבִיב לִירֵאָיו וַיְחַלְּצֵם: טַעֲמוּ וּרְאוּ כִּי טוֹב יהוה, אַשְׁרֵי הַגֶּבֶר יֶחֱסֶה בּוֹ: יְראוּ אֶת יהוה קְדוֹשָׁיו, כִּי אֵין מַחְסוֹר לִירֵאָיו: כְּפִירִים רָשׁוּ וְרָעֵבוּ, וְדוֹרְשֵׁי יהוה לֹא יַחְסְרוּ כָל טוֹב: לְכוּ בָנִים שִׁמְעוּ לִי, יִרְאַת יהוה אֲלַמֶּדְכֶם: מִי הָאִישׁ הֶחָפֵץ חַיִּים, אֹהֵב יָמִים לִרְאוֹת טוֹב: נְצֹר לְשׁוֹנְךָ מֵרָע, וּשפָתֶיךָ מִדַּבֵּר מִרְמָה: סוּר מֵרָע וַעֲשֵׂה טוֹב, בַּקֵּשׁ שָׁלוֹם וְרָדְפֵהוּ: עֵינֵי יהוה אֶל צַדִּיקִים, וְאָזְנָיו אֶל שַׁוְעָתָם: פְּנֵי יהוה בְּעֹשֵׂי רָע, לְהַכְרִית מֵאֶרֶץ זִכְרָם: צָעֲקוּ וַיהוה שָׁמֵעַ, וּמִכָּל צָרוֹתָם הִצִּילָם: קָרוֹב יהוה לְנִשְׁבְּרֵי לֵב, וְאֶת דַּכְּאֵי רוּחַ יוֹשִׁיעַ: רַבּוֹת רָעוֹת צַדִּיק, וּמִכֻּלָּם יַצִּילֶנּוּ יהוה: שֹׁמֵר כָּל עַצְמוֹתָיו, אַחַת מֵהֵנָּה לֹא נִשְׁבָּרָה: תְּמוֹתֵת רָשָׁע רָעָה, וְשֹׂנְאֵי צַדִּיק יֶאְשָׁמוּ: פּוֹדֶה יהוה נֶפֶשׁ עֲבָדָיו, וְלא יֶאְשְׁמוּ כָּל הַחוֹסִים בּוֹ:\n\nתְּפִלָּה לְמֹשֶׁה אִישׁ הָאֱלֹהִים, אֲדֹנָי מָעוֹן אַתָּה הָיִיתָ לָּנוּ, בְּדוֹר וָדֹר: בְּטֶרֶם הָרִים יֻלָּדוּ וַתְּחוֹלֵל אֶרֶץ וְתֵבֵל, וּמֵעוֹלָם עַד עוֹלָם אַתָּה אֵל: תָּשֵׁב אֱנוֹשׁ עַד דַּכָּא, וַתֹּאמֶר שׁוּבוּ בְנֵי אָדָם: כִּי אֶלֶף שָׁנִים בְּעֵינֶיךָ כְּיוֹם אֶתְמול כִּי יַעֲבֹר, וְאַשְׁמוּרָה בַלָּיְלָה: זְרַמְתָּם שֵׁנָה יִהְיוּ, בַּבֹּקֶר כֶּחָצִיר יַחֲלֹף: בַּבֹּקֶר יָצִיץ וְחָלָף, לָעֶרֶב יְמוֹלֵל וְיָבֵשׁ: כִּי כָלִינוּ בְאַפֶּךָ, וּבַחֲמָתְךָ נִבְהָלְנוּ: שַׁתָּה עֲוׂנוֹתֵינוּ לְנֶגְדֶּךָ, עֲלֻמֵנוּ לִמְאוֹר פָּנֶיךָ: כִּי כָל יָמֵינוּ פָּנוּ בְעֶבְרָתֶךָ, כִּלִּינוּ שָׁנֵינוּ כְּמוֹ הֶגֶה: יְמֵי שְׁנוֹתֵינוּ בָּהֶם שִׁבְעִים שָׁנָה, וְאִם בִּגְבוּרֹת שְׁמוֹנִים שָׁנָה, וְרָהְבָּם עָמָל וָאָוֶן, כִּי גָז חִישׁ וַנָּעֻפָה: מִי יוֹדֵעַ עֹז אַפֶּךָ, וּכְיִרְאָתְךָ עֶבְרָתֶךָ: לִמְנוֹת יָמֵינוּ כֵּן הוֹדַע, וְנָבִיא לְבַב חָכְמָה: שׁוּבָה יהוה עַד מָתָי, וְהִנָּחֵם עַל עֲבָדֶיךָ: שַׂבְּעֵנוּ בַבֹּקֶר חַסְדֶּךָ, וּנְרַנְּנָה וְנִשמְחָה בְּכָל יָמֵינוּ: שַׂמְּחֵנוּ כִּימות עִנִּיתָנוּ, שְׁנוֹת רָאִינוּ רָעָה: יֵרָאֶה אֶל עֲבָדֶיךָ פָעֳלֶךָ, וַהֲדָרְךָ עַל בְּנֵיהֶם: וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ:\n\nיֹשֵׁב בְּסֵתֶר עֶלְיוֹן, בְּצֵל שַׁדַּי יִתְלוֹנָן: אֹמַר לַיהוה מַחְסִי וּמְצוּדָתִי, אֱלֹהַי אֶבְטַח בּוֹ: כִּי הוּא יַצִּילְךָ מִפַּח יָקוּשׁ, מִדֶּבֶר הַוּוֹת: בְּאֶבְרָתו יָסֶךְ לָךְ, וְתַחַת כְּנָפָיו תֶּחְסֶה, צִנָּה וְסוֹחֵרָה אֲמִתּוֹ: לא תִירָא מִפַּחַד לָיְלָה, מֵחֵץ יָעוּף יוֹמָם: מִדֶּבֶר בָּאֹפֶל יַהֲלֹךְ, מִקֶּטֶב יָשׁוּד צָהֳרָיִם: יִפֹּל מִצִּדְּךָ אֶלֶף וּרְבָבָה מִימִינֶךָ, אֵלֶיךָ לֹא יִגָּשׁ: רַק בְּעֵינֶיךָ תַבִּיט, וְשִׁלֻּמַת רְשָׁעִים תִּרְאֶה: כִּי אַתָּה יהוה מַחְסִי, עֶלְיוֹן שמְתָּ מְעוֹנֶךָ: לא תְאֻנֶּה אֵלֶיךָ רָעָה, וְנֶגַע לא יִקְרַב בְּאָהֳלֶךָ: כִּי מַלְאָכָיו יְצַוֶּה לָּךְ, לִשְׁמָרְךָ בְּכָל דְּרָכֶיךָ: עַל כַּפַּיִם יִשָּׂאוּנְךָ, פֶּן תִּגּוֹף בָּאֶבֶן רַגְלֶךָ: עַל שַׁחַל וָפֶתֶן תִּדְרוֹךְ, תִּרְמוֹס כְּפִיר וְתַנִּין: כִּי בִי חָשַׁק וַאֲפַלְּטֵהוּ, אֲשַׂגְּבֵהוּ כִּי יָדַע שְׁמִי: יִקְרָאֵנִי וְאֶעֱנֵהוּ, עִמּוֹ אָנֹכִי בְצָרָה, אֲחַלְּצֵהוּ וַאֲכַבְּדֵהוּ: אֹרֶךְ יָמִים אַשְׂבִּיעֵהוּ, וְאַרְאֵהוּ בִּישׁוּעָתִי: אֹרֶךְ יָמִים אַשְׂבִּיעֵהוּ, וְאַרְאֵהוּ בִּישׁוּעָתִי:\n\nמִזְמוֹר שִׁירוּ לַיהוה שִׁיר חָדָשׁ, כִּי נִפְלָאוֹת עָשָׂה: הוֹשִׁיעָה לּוֹ יְמִינוֹ וּזְרוֹעַ קָדְשׁוֹ: הוֹדִיעַ יהוה יְשׁוּעָתוֹ, לְעֵינֵי הַגּוֹיִם גִּלָּה צִדְקָתוֹ: זָכַר חַסְדּוֹ וֶאֱמוּנָתוֹ לְבֵית יִשְׂרָאֵל, רָאוּ כָל אַפְסֵי אָרֶץ אֵת יְשׁוּעַת אֱלֹהֵינוּ: הָרִיעוּ לַיהוה כָּל הָאָרֶץ, פִּצְחוּ וְרַנְּנוּ וְזַמֵּרוּ: זַמְּרוּ לַיהוה בְּכִנּוֹר, בְּכִנּוֹר וְקוֹל זִמְרָה: בַּחֲצֹצְרוֹת וְקוֹל שׁוֹפָר, הָרִיעוּ לִפְנֵי הַמֶּלֶךְ יהוה: יִרְעַם הַיָּם וּמְלֹאוֹ, תֵּבֵל וְיֹשְׁבֵי בָהּ: נְהָרוֹת יִמְחֲאוּ כָף, יַחַד הָרִים יְרַנֵּנוּ: לִפְנֵי יהוה כִּי בָא לִשְׁפֹּט הָאָרֶץ, יִשְׁפֹּט תֵּבֵל בְּצֶדֶק וְעַמִּים בְּמֵישָׁרִים:\n\nשִׁיר הַמַּעֲלוֹת לְדָוִד, שָׂמַחְתִּי בְּאֹמְרִים לִי בֵּית יהוה נֵלֵךְ: עֹמְדוֹת הָיוּ רַגְלֵינוּ בִּשְׁעָרַיִךְ יְרוּשָׁלָיִם: יְרוּשָׁלַיִם הַבְּנוּיָה, כְּעִיר שֶׁחֻבְּרָה לָהּ יַחְדָּו: שֶׁשָּׁם עָלוּ שְׁבָטִים שִׁבְטֵי יָהּ עֵדוּת לְיִשְׂרָאֵל, לְהוֹדוֹת לְשֵׁם יהוה: כִּי שָׁמָּה יָשְׁבוּ כִסְאוֹת לְמִשְׁפָּט, כִּסְאוֹת לְבֵית דָּוִד: שַׁאֲלוּ שְׁלוֹם יְרוּשָׁלָיִם, יִשְׁלָיוּ אֹהֲבָיִךְ: יְהִי שָׁלוֹם בְּחֵילֵךְ, שַׁלְוָה בְּאַרְמְנֹתָיִךְ: לְמַעַן אַחַי וְרֵעָי, אֲדַבְּרָה נָּא שָׁלוֹם בָּךְ: לְמַעַן בֵּית יהוה אֱלֹהֵינוּ, אֲבַקְשָׁה טוֹב לָךְ:\n\nשִׁיר הַמַּעֲלוֹת, אֵלֶיךָ נָשָׂאתִי אֶת עֵינַי הַיּוֹשְׁבִי בַּשָּׁמָיִם: הִנֵּה כְעֵינֵי עֲבָדִים אֶל יַד אֲדוֹנֵיהֶם, כְּעֵינֵי שִׁפְחָה אֶל יַד גְּבִרְתָּהּ, כֵּן עֵינֵינוּ אֶל יהוה אֱלֹהֵינוּ עַד שֶׁיְּחָנֵּנוּ: חָנֵּנוּ יהוה חָנֵּנוּ, כִּי רַב שָׂבַעְנוּ בוּז: רַבַּת שָׂבְעָה לָּהּ נַפְשֵׁנוּ הַלַּעַג הַשַּׁאֲנַנִּים, הַבּוּז לִגְאֵי יוֹנִים:\n\nשִׁיר הַמַּעֲלוֹת לְדָוִד, לוּלֵי יהוה שֶׁהָיָה לָנוּ יֹאמַר נָא יִשְׂרָאֵל: לוּלֵי יהוה שֶׁהָיָה לָנוּ, בְּקוּם עָלֵינוּ אָדָם: אֲזַי חַיִּים בְּלָעוּנוּ, בַּחֲרוֹת אַפָּם בָּנוּ: אֲזַי הַמַּיִם שְׁטָפוּנוּ, נַחְלָה עָבַר עַל נַפְשֵׁנוּ: אֲזַי עָבַר עַל נַפְשֵׁנוּ, הַמַּיִם הַזֵּידוֹנִים: בָּרוּךְ יהוה, שֶׁלֹּא נְתָנָנוּ טֶרֶף לְשִׁנֵּיהֶם: נַפְשֵׁנוּ כְּצִפּוֹר נִמְלְטָה מִפַּח יוֹקְשִׁים, הַפַּח נִשְׁבָּר וַאֲנַחְנוּ נִמְלָטְנוּ: עֶזְרֵנוּ בְּשֵׁם יהוה, עֹשֵׂה שָׁמַיִם וָאָרֶץ:\n\nהַלְלוּיָהּ, הַלְלוּ אֶת שֵׁם יהוה, הַלְלוּ עַבְדֵי יהוה: שֶׁעוֹמְדִים בְּבֵית יהוה, בְּחַצְרוֹת בֵּית אֱלֹהֵינוּ: הַלְלוּיָהּ כִּי טוֹב יהוה, זַמְּרוּ לִשְׁמוֹ כִּי נָעִים: כִּי יַעֲקֹב בָּחַר לוֹ יָהּ, יִשְׂרָאֵל לִסְגֻלָּתו: כִּי אֲנִי יָדַעְתִּי כִּי גָּדוֹל יהוה, וַאֲדֹנֵינוּ מִכָּל אֱלֹהִים: כֹּל אֲשֶׁר חָפֵץ יהוה עָשָׂה, בַּשָּׁמַיִם וּבָאָרֶץ בַּיַּמִּים וְכָל תְּהֹמֹת: מַעֲלֶה נְשִׂאִים מִקְצֵה הָאָרֶץ, בְּרָקִים לַמָּטָר עָשָׂה, מוֹצֵא רוּחַ מֵאוֹצְרוֹתָיו: שֶׁהִכָּה בְּכוֹרֵי מִצְרָיִם, מֵאָדָם עַד בְּהֵמָה: שָׁלַח אוֹתֹת וּמוֹפְתִים בְּתוֹכֵכִי מִצְרָיִם, בְּפַרְעֹה וּבְכָל עֲבָדָיו: שֶׁהִכָּה גּוֹיִם רַבִּים, וְהָרַג מְלָכִים עֲצוּמִים: לְסִיחוֹן מֶלֶךְ הָאֱמֹרִי וּלְעוֹג מֶלֶךְ הַבָּשָׁן, וּלְכֹל מַמְלְכוֹת כְּנָעַן: וְנָתַן אַרְצָם נַחֲלָה, נַחֲלָה לְיִשְׂרָאֵל עַמּוֹ: יהוה שִׁמְךָ לְעוֹלָם, יהוה זִכְרְךָ לְדֹר וָדֹר: כִּי יָדִין יהוה עַמּוֹ, וְעַל עֲבָדָיו יִתְנֶחָם: עֲצַבֵּי הַגּוֹיִם כֶּסֶף וְזָהָב, מַעֲשֵׂה יְדֵי אָדָם: פֶּה לָהֶם וְלֹא יְדַבֵּרוּ, עֵינַיִם לָהֶם וְלֹא יִרְאוּ: אָזְנַיִם לָהֶם וְלֹא יַאֲזִינוּ, אַף אֵין יֶשׁ רוּחַ בְּפִיהֶם: כְּמוֹהֶם יִהְיוּ עֹשֵׂיהֶם, כֹּל אֲשֶׁר בֹּטֵחַ בָּהֶם: בֵּית יִשְׂרָאֵל בָּרְכוּ אֶת יהוה, בֵּית אַהֲרֹן בָּרְכוּ אֶת יהוה: בֵּית הַלֵּוִי בָּרְכוּ אֶת יהוה, יִרְאֵי יהוה בָּרְכוּ אֶת יהוה: בָּרוּךְ יהוה מִצִּיּוֹן, שֹׁכֵן יְרוּשָׁלָיִם, הַלְלוּיָהּ:\n\nהוֹדוּ ליהוה כִּי טוֹב, כִּי לְעוֹלָם חַסְדּו:\nהוֹדוּ לֵאלֹהֵי הָאֱלֹהִים, כִּי לְעוֹלָם חַסְדּוֹ:\nהוֹדוּ לַאֲדֹנֵי הָאֲדֹנִים, כִּי לְעוֹלָם חַסְדּוֹ:\nלְעֹשֵׂה נִפְלָאוֹת גְּדֹלוֹת לְבַדּוֹ, כִּי לְעוֹלָם חַסְדּוֹ:\nלְעֹשֵׂה הַשָּׁמַיִם בִּתְבוּנָה, כִּי לְעוֹלָם חַסְדּוֹ:\nלְרוֹקַע הָאָרֶץ עַל הַמָּיִם, כִּי לְעוֹלָם חַסְדּוֹ:\nלְעֹשֵׂה אוֹרִים גְּדֹלִים, כִּי לְעוֹלָם חַסְדּוֹ:\nאֶת הַשֶּׁמֶשׁ לְמֶמְשֶׁלֶת בַּיּוֹם, כִּי לְעוֹלָם חַסְדּוֹ:\nאֶת הַיָּרֵחַ וְכוֹכָבִים לְמֶמְשְׁלוֹת בַּלָּיְלָה, כִּי לְעוֹלָם חַסְדּוֹ:\nלְמַכֵּה מִצְרַיִם בִּבְכוֹרֵיהֶם, כִּי לְעוֹלָם חַסְדּוֹ:\nוַיּוֹצֵא יִשְׂרָאֵל מִתּוֹכָם, כִּי לְעוֹלָם חַסְדּוֹ:\nבְּיָד חֲזָקָה וּבִזְרוֹעַ נְטוּיָה, כִּי לְעוֹלָם חַסְדּוֹ:\nלְגֹזֵר יַם סוּף לִגְזָרִים, כִּי לְעוֹלָם חַסְדּוֹ:\nוְהֶעֱבִיר יִשְׂרָאֵל בְּתוֹכוֹ, כִּי לְעוֹלָם חַסְדּוֹ:\nוְנִעֵר פַּרְעֹה וְחֵילוֹ בְיַם סוּף, כִּי לְעוֹלָם חַסְדּוֹ:\nלְמוֹלִיךְ עַמּוֹ בַּמִּדְבָּר, כִּי לְעוֹלָם חַסְדּוֹ:\nלְמַכֵּה מְלָכִים גְּדֹלִים, כִּי לְעוֹלָם חַסְדּוֹ:\nוַיַּהֲרֹג מְלָכִים אַדִּירִים, כִּי לְעוֹלָם חַסְדּוֹ:\nלְסִיחוֹן מֶלֶךְ הָאֱמֹרִי, כִּי לְעוֹלָם חַסְדּוֹ:\nוּלְעוֹג מֶלֶךְ הַבָּשָׁן, כִּי לְעוֹלָם חַסְדּוֹ:\nוְנָתַן אַרְצָם לְנַחֲלָה, כִּי לְעוֹלָם חַסְדּוֹ:\nנַחֲלָה לְיִשְׂרָאֵל עַבְדּוֹ, כִּי לְעוֹלָם חַסְדּוֹ:\nשֶׁבְּשִׁפְלֵנוּ זָכַר לָנוּ, כִּי לְעוֹלָם חַסְדּוֹ:\nוַיִּפְרְקֵנוּ מִצָּרֵינוּ, כִּי לְעוֹלָם חַסְדּוֹ:\nנוֹתֵן לֶחֶם לְכָל בָּשָׂר, כִּי לְעוֹלָם חַסְדּוֹ:\nהוֹדוּ לְאֵל הַשָּׁמָיִם, כִּי לְעוֹלָם חַסְדּוֹ:","cond":["shabbat"]},{"kind":"header","text":"למנצח","cond":["noShabbat"]},{"kind":"text","text":"לַמְנַצֵּחַ בִּנְגִינֹת מִזְמוֹר שִׁיר: אֱלֹהִים יְחָנֵּנוּ וִיבָרְכֵנוּ, יָאֵר פָּנָיו אִתָּנוּ סֶלָה: לָדַעַת בָּאָרֶץ דַּרְכֶּךָ, בְּכָל-גּוֹיִם יְשׁוּעָתֶךָ: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: יִשְׂמְחוּ וִירַנְּנוּ לְאֻמִּים כִּי-תִשְׁפֹּט עַמִּים מִישֹׁר, וּלְאֻמִּים בָּאָרֶץ תַּנְחֵם סֶלָה: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: אֶרֶץ נָתְנָה יְבוּלָהּ, יְבָרְכֵנוּ אֱלֹהִים אֱלֹהֵינוּ: יְבָרְכֵנוּ אֱלֹהִים, וְיִירְאוּ אוֹתוֹ כָּל-אַפְסֵי-אָרֶץ:","cond":["noShabbat"]},{"kind":"instruction","text":"הלכות ברוך שאמר ופסוקי דזמרה\n\nאסור לענות אמן על ברכות באמצע ברוך שאמר, ואפילו על ברכת ברוך שאמר של חבירו. דברים אלו אמורים רק אם כבר התחיל \"ברוך אתה יהוה אלהינו\" וכו', אבל לפני זה מותר לענות אמן על כל הברכות.\n\nבמשך פסוקי דזמרה מותר לענות אמן על ברכות וכן מותר לענות \"אמן יהא שמיה רבה מברך\" וכו' עד \"דאמירן בעלמא\", אבל לא יענה \"ברוך הוא וברוך שמו\", או אמן של \"על ישראל\" או \"יהא שלמא רבא\" וכו'.\n\nהשומע קדושה באמצע פסוקי דזמרה יאמר רק את הפסוקים קדוש, ברוך וימלוך, אבל לא את שאר נוסח הקדושה.\n\nבמודים דרבנן רק ישחה ויאמר \"מודים אנחנו לך\".\n\nאם עומד בין ישתבח ליוצר, יאמר את כל נוסח הקדושה וכל מודים דרבנן.\n\nאם הגיע הציבור לקריאת שמע, יכסה עיניו ויאמר את המילים שהוא נמצא בהן (לא את קריאת שמע) בניגון של קריאת שמע.\n\nאם קראוהו לעלות לתורה, יעלה ויקרא בלחש מהספר כרגיל.","cond":[]},{"kind":"header","text":"ברוך שאמר","cond":[]},{"kind":"text","text":"כִּי גָבַר עָלֵינוּ חַסְדּוֹ, וֶאֱמֶת יהוה לְעוֹלָם הַלְלוּיָהּ:","cond":[]},{"kind":"instruction","text":"יאחז ביד ימינו בשתי הציציות שלפניו, ויאמר \"ברוך שאמר\" בעמידה, ובסוף הברכה ינשקן ויניחן, ויאמר הזמירות בקול רם ונעים ובמתון.","cond":[]},{"kind":"text","text":"בָּרוּךְ שֶׁאָמַר וְהָיָה הָעוֹלָם, בָּרוּךְ הוּא. בָּרוּךְ אוֹמֵר וְעֹשֶׂה, בָּרוּךְ גּוֹזֵר וּמְקַיֵּם. בָּרוּךְ עֹשֶׂה בְרֵאשִׁית, בָּרוּךְ מְרַחֵם עַל הָאָרֶץ. בָּרוּךְ מְרַחֵם עַל הַבְּרִיּוֹת, בָּרוּךְ מְשַׁלֵּם שָׂכָר טוֹב לִירֵאָיו. בָּרוּךְ חַי לָעַד וְקַיָּם לָנֶצַח, בָּרוּךְ פּוֹדֶה וּמַצִּיל בָּרוּךְ שְׁמוֹ. בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הָאֵל אָב הָרַחֲמָן המְהֻלָּל בְּפֶה עַמּוֹ, מְשֻׁבָּח וּמְפֹאָר בִּלְשׁוֹן חֲסִידָיו וַעֲבָדָיו, וּבְשִׁירֵי דָּוִד עַבְדָּךָ נְהַלְלָךְ יהוה אֱלֹהֵינוּ בִּשְׁבָחות וּבִזְמִירוֹת וּנְגַדְּלָךְ וּנְשַׁבְּחָךְ וּנְפָאֲרָךְ וְנַמְלִיכָךְ וְנַזְכִּיר שִׁמְךָ מַלְכֵּנוּ, אֱלֹהֵינוּ, יָחִיד, חַי הָעוֹלָמִים, מֶלֶךְ מְשֻׁבָּח וּמְפֹאָר עֲדֵי עַד שְׁמוֹ הַגָּדוֹל. בָּרוּךְ אַתָּה יהוה, מֶלֶךְ מְהֻלָּל בַּתִּשְׁבָּחוֹת.","cond":[]},{"kind":"text","text":"מִזְמוֹר לְתוֹדָה, הָרִיעוּ לַיהוה כָּל הָאָרֶץ: עִבְדוּ אֶת יהוה בְּשִׂמְחָה, בֹּאוּ לְפָנָיו בִּרְנָנָה: דְּעוּ כִּי יהוה הוּא אֱלֹהִים, הוּא עָשָׂנוּ וְלוֹ אֲנַחְנוּ, עַמּוֹ וְצֹאן מַרְעִיתוֹ: בֹּאוּ שְׁעָרָיו בְּתוֹדָה, חֲצֵרֹתָיו בִּתְהִלָּה, הוֹדוּ לוֹ בָּרְכוּ שְׁמוֹ: כִּי טוֹב יהוה, לְעוֹלָם חַסְדּוֹ, וְעַד דֹּר וָדֹר אֱמוּנָתוֹ:","cond":[]},{"kind":"text","text":"(ש) יְהִי כְבוֹד יהוה לְעוֹלָם, יִשְׂמַח יהוה בְּמַעֲשָׂיו:\n(ד) יְהִי שֵׁם יהוה מְבֹרָךְ, מֵעַתָּה וְעַד עוֹלָם:\n(י) מִמִּזְרַח שֶׁמֶשׁ עַד מְבוֹאוֹ, מְהֻלָּל שֵׁם יהוה:\n(ש) רָם עַל כָּל גּוֹיִם יהוה, עַל הַשָּׁמַיִם כְּבוֹדוֹ:\n(י) יהוה שִׁמְךָ לְעוֹלָם, יהוה זִכְרְךָ לְדֹר וָדֹר:\n(ד) יהוה בַּשָּׁמַיִם הֵכִין כִּסְאוֹ, וּמַלְכוּתוֹ בַּכֹּל מָשָׁלָה:\n(ד) יִשְׂמְחוּ הַשָּׁמַיִם וְתָגֵל הָאָרֶץ, וְיֹאמְרוּ בַגּוֹיִם יהוה מָלָךְ:\n(י) יהוה מֶלֶךְ, יהוה מָלָךְ, יהוה יִמְלֹךְ לְעוֹלָם וָעֶד.\n(ש) יהוה מֶלֶךְ עוֹלָם וָעֶד, אָבְדוּ גוֹיִם מֵאַרְצוֹ:\n(ד) יהוה הֵפִיר עֲצַת גּוֹיִם, הֵנִיא מַחְשְׁבוֹת עַמִּים:\n(ש) רַבּוֹת מַחֲשָׁבוֹת בְּלֶב אִישׁ, וַעֲצַת יהוה הִיא תָקוּם:\n(י) עֲצַת יהוה לְעוֹלָם תַּעֲמֹד, מַחְשְׁבוֹת לִבּוֹ לְדֹר וָדֹר:\n(י) כִּי הוּא אָמַר וַיֶּהִי, הוּא צִוָּה וַיַּעֲמֹד:\n(ש) כִּי בָחַר יהוה בְּצִיּוֹן, אִוָּהּ לְמוֹשָׁב לוֹ:\n(ד) כִּי יַעֲקֹב בָּחַר לוֹ יָהּ, יִשְׂרָאֵל לִסְגֻלָּתוֹ:\n(י) כִּי לֹא יִטֹּשׁ יהוה עַמּוֹ, וְנַחֲלָתוֹ לֹא יַעֲזֹב:\n(ד) וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית וְהִרְבָּה לְהָשִׁיב אַפּוֹ, וְלֹא יָעִיר כָּל חֲמָתוֹ:\n(ש) יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":[]},{"kind":"header","text":"אשרי","cond":[]},{"kind":"text","text":"אַשְׁרֵי יוֹשְׁבֵי בֵיתֶךָ עוֹד יְהַלְלוּךָ סֶּלָה:\nאַשְׁרֵי הָעָם שֶׁכָּכָה לּוֹ אַשְׁרֵי הָעָם שֶׁיהוה אֱלֹהָיו:\nתְּהִלָּה לְדָוִד, אֲרוֹמִמְךָ אֱלוֹהַי הַמֶּלֶךְ וַאֲבָרְכָה שִׁמְךָ לְעוֹלָם וָעֶד:\nבְּכָל יוֹם אֲבָרְכֶךָּ וַאֲהַלְלָה שִׁמְךָ לְעוֹלָם וָעֶד:\nגָּדוֹל יהוה וּמְהֻלָּל מְאֹד וְלִגְדֻלָּתוֹ אֵין חֵקֶר:\nדּוֹר לְדוֹר יְשַׁבַּח מַעֲשֶׂיךָ וּגְבוּרֹתֶיךָ יַגִּידוּ:\nהֲדַר כְּבוֹד הוֹדֶךָ וְדִבְרֵי נִפְלְאוֹתֶיךָ אָשִׂיחָה:\nוֶעֱזוּז נוֹרְאֹתֶיךָ יֹאמֵרוּ וּגְדוּלָּתְךָ אֲסַפְּרֶנָּה:\nזֵכֶר רַב טוּבְךָ יַבִּיעוּ וְצִדְקָתְךָ יְרַנֵּנוּ:","cond":[]},{"kind":"text","text":"חַנּוּן וְרַחוּם יהוה אֶרֶךְ אַפַּיִם וּגְדָל חָסֶד:\nטוֹב יהוה לַכֹּל וְרַחֲמָיו עַל כָּל מַעֲשָׂיו:\nיוֹדוּךָ יהוה כָּל מַעֲשֶׂיךָ וַחֲסִידֶיךָ יְבָרְכוּכָה:\nכְּבוֹד מַלְכוּתְךָ יֹאמֵרוּ וּגְבוּרָתְךָ יְדַבֵּרוּ:\nלְהוֹדִיעַ לִבְנֵי הָאָדָם גְּבוּרֹתָיו וּכְבוֹד הֲדַר מַלְכוּתוֹ:\nמַלְכוּתְךָ מַלְכוּת כָּל עֹלָמִים וּמֶמְשַׁלְתְּךָ בְּכָל דּוֹר וָדוֹר:\nסוֹמֵךְ יהוה לְכָל הַנֹּפְלִים וְזוֹקֵף לְכָל הַכְּפוּפִים:\nעֵינֵי כֹל אֵלֶיךָ יְשַׂבֵּרוּ וְאַתָּה נוֹתֵן לָהֶם אֶת אָכְלָם בְּעִתּוֹ:","cond":[]},{"kind":"text","text":"פּוֹתֵחַ אֶת יָדֶךָ וּמַשְׂבִּיעַ לְכָל חַי רָצוֹן:\nצַדִּיק יהוה בְּכָל דְּרָכָיו וְחָסִיד בְּכָל מַעֲשָׂיו:\nקָרוֹב יהוה לְכָל קֹרְאָיו לְכֹל אֲשֶׁר יִקְרָאֻהוּ בֶאֱמֶת:\nרְצוֹן יְרֵאָיו יַעֲשֶׂה וְאֶת שַׁוְעָתָם יִשְׁמַע וְיוֹשִׁיעֵם:\nשׁוֹמֵר יהוה אֶת כָּל אֹהֲבָיו וְאֵת כָּל הָרְשָׁעִים יַשְׁמִיד:\nתְּהִלַּת יהוה יְדַבֶּר פִּי וִיבָרֵךְ כָּל בָּשָׂר שֵׁם קָדְשׁוֹ לְעוֹלָם וָעֶד:\nוַאֲנַחְנוּ נְבָרֵךְ יָהּ מֵעַתָּה וְעַד עוֹלָם הַלְלוּיָהּ:","cond":[]},{"kind":"text","text":"הַלְלוּיָהּ, הַלְלִי נַפְשִׁי אֶת יהוה: אֲהַלְלָה יהוה בְּחַיָּי, אֲזַמְּרָה לֵאלֹהַי בְּעוֹדִי: אַל תִּבְטְחוּ בִנְדִיבִים, בְּבֶן אָדָם שֶׁאֵין לוֹ תְשׁוּעָה: תֵּצֵא רוּחוֹ, יָשֻׁב לְאַדְמָתוֹ, בַּיּוֹם הַהוּא אָבְדוּ עֶשְׁתֹּנֹתָיו: אַשְׁרֵי שֶׁאֵל יַעֲקֹב בְּעֶזְרוֹ, שִׂבְרוֹ עַל יהוה אֱלֹהָיו: עֹשֶׂה שָׁמַיִם וָאָרֶץ, אֶת הַיָּם וְאֶת כָּל אֲשֶׁר בָּם, הַשֹּׁמֵר אֱמֶת לְעוֹלָם: עֹשֶׂה מִשְׁפָּט לָעֲשׁוּקִים, נֹתֵן לֶחֶם לָרְעֵבִים, יהוה מַתִּיר אֲסוּרִים: יהוה פֹּקֵחַ עִוְרִים, יהוה זֹקֵף כְּפוּפִים, יהוה אֹהֵב צַדִּיקִים: יהוה שֹׁמֵר אֶת גֵּרִים, יָתוֹם וְאַלְמָנָה יְעוֹדֵד וְדֶרֶךְ רְשָׁעִים יְעַוֵּת: יִמְלֹךְ יהוה לְעוֹלָם, אֱלֹהַיִךְ צִיּוֹן לְדֹר וָדֹר, הַלְלוּיָהּ:","cond":[]},{"kind":"text","text":"הַלְלוּיָהּ, כִּי טוֹב זַמְּרָה אֱלֹהֵינוּ, כִּי נָעִים נָאוָה תְהִלָּה: בּוֹנֵה יְרוּשָׁלַיִם יהוה, נִדְחֵי יִשְׂרָאֵל יְכַנֵּס: הָרֹפֵא לִשְׁבוּרֵי לֵב וּמְחַבֵּשׁ לְעַצְּבוֹתָם: מוֹנֶה מִסְפָּר לַכּוֹכָבִים, לְכֻלָּם שֵׁמוֹת יִקְרָא: גָּדוֹל אֲדוֹנֵינוּ וְרַב כֹּחַ, לִתְבוּנָתוֹ אֵין מִסְפָּר: מְעוֹדֵד עֲנָוִים יהוה, מַשְׁפִּיל רְשָׁעִים עֲדֵי אָרֶץ: עֱנוּ לַיהוה בְּתוֹדָה, זַמְּרוּ לֵאלֹהֵינוּ בְכִנּוֹר: הַמְכַסֶּה שָׁמַיִם בְּעָבִים, הַמֵּכִין לָאָרֶץ מָטָר, הַמַּצְמִיחַ הָרִים חָצִיר: נוֹתֵן לִבְהֵמָה לַחְמָהּ, לִבְנֵי עֹרֵב אֲשֶׁר יִקְרָאוּ: לֹא בִגְבוּרַת הַסּוּס יֶחְפָּץ, לֹא בְשׁוֹקֵי הָאִישׁ יִרְצֶה: רוֹצֶה יהוה אֶת יְרֵאָיו, אֶת הַמְיַחֲלִים לְחַסְדּוֹ: שַׁבְּחִי יְרוּשָׁלַיִם אֶת יהוה, הַלְלִי אֱלֹהַיִךְ צִיּוֹן: כִּי חִזַּק בְּרִיחֵי שְׁעָרָיִךְ, בֵּרַךְ בָּנַיִךְ בְּקִרְבֵּךְ: הַשָּׂם גְּבוּלֵךְ שָׁלוֹם, חֵלֶב חִטִּים יַשְׂבִּיעֵךְ: הַשֹּׁלֵחַ אִמְרָתוֹ אָרֶץ, עַד מְהֵרָה יָרוּץ דְּבָרוֹ: הַנֹּתֵן שֶׁלֶג כַּצָּמֶר, כְּפוֹר כָּאֵפֶר יְפַזֵּר: מַשְׁלִיךְ קַרְחוֹ כְפִתִּים, לִפְנֵי קָרָתוֹ מִי יַעֲמֹד: יִשְׁלַח דְּבָרוֹ וְיַמְסֵם, יַשֵּׁב רוּחוֹ יִזְּלוּ מָיִם: מַגִּיד דְּבָרָיו לְיַעֲקֹב, חֻקָּיו וּמִשְׁפָּטָיו לְיִשְׂרָאֵל: לֹא עָשָׂה כֵן לְכָל גּוֹי, וּמִשְׁפָּטִים בַּל יְדָעוּם, הַלְלוּיָהּ:","cond":[]},{"kind":"text","text":"הַלְלוּיָהּ, הַלְלוּ אֶת יהוה מִן הַשָּׁמַיִם, הַלְלוּהוּ בַּמְּרוֹמִים: הַלְלוּהוּ כָל מַלְאָכָיו, הַלְלוּהוּ כָּל צְבָאָיו: הַלְלוּהוּ שֶׁמֶשׁ וְיָרֵחַ, הַלְלוּהוּ כָּל כּוֹכְבֵי אוֹר: הַלְלוּהוּ שְׁמֵי הַשָּׁמָיִם וְהַמַּיִם אֲשֶׁר מֵעַל הַשָּׁמָיִם: יְהַלְלוּ אֶת שֵׁם יהוה, כִּי הוּא צִוָּה וְנִבְרָאוּ: וַיַּעֲמִידֵם לָעַד לְעוֹלָם, חָק נָתַן וְלֹא יַעֲבוֹר: הַלְלוּ אֶת יהוה מִן הָאָרֶץ, תַּנִּינִים וְכָל תְּהֹמוֹת: אֵשׁ וּבָרָד, שֶׁלֶג וְקִיטוֹר, רוּחַ סְעָרָה עֹשָׂה דְבָרוֹ: הֶהָרִים וְכָל גְּבָעוֹת, עֵץ פְּרִי וְכָל אֲרָזִים: הַחַיָּה וְכָל בְּהֵמָה, רֶמֶשׂ וְצִפּוֹר כָּנָף: מַלְכֵי אֶרֶץ וְכָל לְאֻמִּים, שָׂרִים וְכָל שֹׁפְטֵי אָרֶץ: בַּחוּרִים וְגַם בְּתוּלוֹת, זְקֵנִים עִם נְעָרִים: יְהַלְלוּ אֶת שֵׁם יהוה כִּי נִשְׂגָּב שְׁמוֹ לְבַדּוֹ, הוֹדוֹ עַל אֶרֶץ וְשָׁמָיִם: וַיָּרֶם קֶרֶן לְעַמּוֹ, תְּהִלָּה לְכָל חֲסִידָיו, לִבְנֵי יִשְׂרָאֵל עַם קְרֹבוֹ, הַלְלוּיָהּ:","cond":[]},{"kind":"text","text":"הַלְלוּיָהּ, שִׁירוּ לַיהוה שִׁיר חָדָשׁ, תְּהִלָּתוֹ בִּקְהַל חֲסִידִים: יִשְׂמַח יִשְׂרָאֵל בְּעֹשָׂיו, בְּנֵי צִיּוֹן יָגִילוּ בְמַלְכָּם: יְהַלְלוּ שְׁמוֹ בְמָחוֹל, בְּתֹף וְכִנּוֹר יְזַמְּרוּ לוֹ: כִּי רוֹצֶה יהוה בְּעַמּוֹ, יְפָאֵר עֲנָוִים בִּישׁוּעָה: יַעְלְזוּ חֲסִידִים בְּכָבוֹד, יְרַנְּנוּ עַל מִשְׁכְּבוֹתָם: רוֹמְמוֹת אֵל בִּגְרוֹנָם וְחֶרֶב פִּיפִיּוֹת בְּיָדָם: לַעֲשׂוֹת נְקָמָה בַּגּוֹיִם, תּוֹכֵחֹת בַּלְאֻמִּים: לֶאְסֹר מַלְכֵיהֶם בְּזִקִּים וְנִכְבְּדֵיהֶם בְּכַבְלֵי בַרְזֶל: לַעֲשׂוֹת בָּהֶם מִשְׁפָּט כָּתוּב, הָדָר הוּא לְכָל חֲסִידָיו, הַלְלוּיָהּ:","cond":[]},{"kind":"text","text":"הַלְלוּיָהּ, הַלְלוּ אֵל בְּקָדְשׁוֹ, הַלְלוּהוּ בִּרְקִיעַ עֻזּוֹ: הַלְלוּהוּ בִגְבוּרֹתָיו, הַלְלוּהוּ כְּרֹב גֻּדְלוֹ: הַלְלוּהוּ בְּתֵקַע שׁוֹפָר, הַלְלוּהוּ בְּנֵבֶל וְכִנּוֹר: הַלְלוּהוּ בְתֹף וּמָחוֹל, הַלְלוּהוּ בְּמִנִּים וְעוּגָב: הַלְלוּהוּ בְצִלְצְלֵי שָׁמַע, הַלְלוּהוּ בְּצִלְצְלֵי תְרוּעָה: כֹּל הַנְּשָׁמָה תְּהַלֵּל יָהּ, הַלְלוּיָהּ: כֹּל הַנְּשָׁמָה תְּהַלֵּל יָהּ, הַלְלוּיָהּ:","cond":[]},{"kind":"text","text":"בָּרוּךְ יהוה לְעוֹלָם, אָמֵן וְאָמֵן: בָּרוּך יהוה מִצִּיּוֹן, שֹׁכֵן יְרוּשָׁלַיִם, הַלְלוּיָהּ: בָּרוּךְ יהוה אֱלֹהִים אֱלֹהֵי יִשְׂרָאֵל, עֹשֶׂה נִפְלָאוֹת לְבַדּוֹ: וּבָרוּךְ שֵׁם כְּבוֹדוֹ לְעוֹלָם, וְיִמָּלֵא כְבוֹדוֹ אֶת כָּל הָאָרֶץ, אָמֵן וְאָמֵן:","cond":[]},{"kind":"text","text":"וַיְבָרֶךְ דָּוִד אֶת יהוה לְעֵינֵי כָּל הַקָּהָל, וַיֹּאמֶר דָּוִד: בָּרוּךְ אַתָּה יהוה אֱלֹהֵי יִשְׂרָאֵל אָבִינוּ, מֵעוֹלָם וְעַד עוֹלָם: לְךָ יהוה הַגְּדֻלָּה, וְהַגְּבוּרָה, וְהַתִּפְאֶרֶת וְהַנֵּצַח וְהַהוֹד, כִּי כָל בַּשָּׁמַיִם וּבָאָרֶץ, לְךָ יהוה הַמַּמְלָכָה וְהַמִּתְנַשֵּׂא לְכָל לְרֹאשׁ: וְהָעֹשֶׁר וְהַכָּבוֹד מִלְּפָנֶיךָ, וְאַתָּה מוֹשֵׁל בַּכֹּל, וּבְיָדְךָ כֹּחַ וּגְבוּרָה וּבְיָדְךָ לְגַדֵּל וּלְחַזֵּק לַכֹּל: וְעַתָּה אֱלֹהֵינוּ מוֹדִים אֲנַחְנוּ לָךְ, וּמְהַלְלִים לְשֵׁם תִפְאַרְתֶּךְ: וִיבָרְכוּ שֵׁם כְּבֹדֶךָ, וּמֱרוֹמַם עַל כָּל בְּרָכָה וּתְהִלָּה: אַתָּה הוּא יהוה לְבַדֶּךָ, אַתָּה עָשִׂיתָ אֶת הַשָּׁמַיִם, שְׁמֵי הַשָּׁמַיִם וְכָל צְבָאָם, הָאָרֶץ וְכָל אֲשֶׁר עָלֶיהָ, הַיַּמִּים וְכָל אֲשֶׁר בָּהֶם, וְאַתָּה מְחַיֶּה אֶת כֻּלָּם, וּצְבָא הַשָּׁמַיִם לְךָ מִשְׁתַּחֲוִים: אַתָּה הוּא יהוה הָאֱלֹהִים אֲשֶׁר בָּחַרְתָּ בְּאַבְרָם וְהוֹצֵאתוֹ מֵאוּר כַּשְׂדִּים, וְשַׂמְתָּ שְׁמוֹ אַבְרָהָם: וּמָצָאתָ אֶת לְבָבוֹ נֶאֱמָן לְפָנֶיךָ, וְכָרוֹת עִמּוֹ הַבְּרִית לָתֵת אֶת אֶרֶץ הַכְּנַעֲנִי, הַחִתִּי, הָאֱמֹרִי וְהַפְּרִזִּי וְהַיְבוּסִי וְהַגִּרְגָּשִׁי לָתֵת לְזַרְעוֹ, וַתָּקֶם אֶת דְּבָרֶיךָ כִּי צַדִּיק אָתָּה: וַתֵּרֶא אֶת עֳנִי אֲבֹתֵינוּ בְּמִצְרָיִם, וְאֶת זַעֲקָתָם שָׁמַעְתָּ עַל יַם סוּף: וַתִּתֵּן אֹתֹת וּמֹפְתִים בְּפַרְעֹה וּבְכָל עֲבָדָיו וּבְכָל עַם אַרְצוֹ, כִּי יָדַעְתָּ כִּי הֵזִידוּ עֲלֵיהֶם, וַתַּעַשׂ לְךָ שֵׁם כְּהַיּוֹם הַזֶּה: וְהַיָּם בָּקַעְתָּ לִפְנֵיהֶם, וַיַּעַבְרוּ בְתוֹךְ הַיָּם בַּיַּבָּשָׁה, וְאֶת רֹדְפֵיהֶם הִשְׁלַכְתָּ בִמְצוֹלֹת כְּמוֹ אֶבֶן, בְּמַיִם עַזִּים:\n\nוַיּוֹשַׁע יהוה בַּיּוֹם הַהוּא אֶת יִשְׂרָאֵל מִיַּד מִצְרָיִם, וַיַּרְא יִשְׂרָאֵל אֶת מִצְרַיִם מֵת, עַל שְׂפַת הַיָּם: וַיַּרְא יִשְׂרָאֵל אֶת הַיָּד הַגְּדֹלָה אֲשֶׁר עָשָׂה יהוה בְּמִצְרַיִם, וַיִּירְאוּ הָעָם אֶת יהוה, וַיַּאֲמִינוּ בַּיהוה וּבְמֹשֶׁה עַבְדּוֹ:","cond":[]},{"kind":"header","text":"שירת הים","cond":[]},{"kind":"text","text":"אָז יָשִׁיר מֹשֶׁה וּבְנֵי יִשְׂרָאֵל אֶת הַשִּׁירָה הַזֹּאת לַיהוה וַיֹּאמְרוּ לֵּאמֹר, אָשִׁירָה לַיהוה כִּי גָאֹה גָּאָה, סוּס וְרֹכְבוֹ רָמָה בַיָּם: עָזִּי וְזִמְרָת יָהּ וַיְהִי לִי לִישׁוּעָה, זֶה אֵלִי וְאַנְוֵהוּ, אֱלֹהֵי אָבִי וַאֲרֹמְמֶנְהוּ: יהוה אִישׁ מִלְחָמָה, יהוה שְׁמוֹ: מַרְכְּבֹת פַּרְעֹה וְחֵילוֹ יָרָה בַיָּם, וּמִבְחַר שָׁלִשָׁיו טֻבְּעוּ בְיַם סוּף: תְּהֹמֹת יְכַסְיֻמוּ, יָרְדוּ בִמְצוֹלֹת כְּמוֹ אָבֶן: יְמִינְךָ יהוה נֶאְדָּרִי בַּכֹּחַ, יְמִינְךָ יהוה תִּרְעַץ אוֹיֵב: וּבְרֹב גְּאוֹנְךָ תַּהֲרֹס קָמֶיךָ, תְּשַׁלַּח חֲרֹנְךָ יֹאכְלֵמוֹ כַּקַּשׁ: וּבְרוּחַ אַפֶּיךָ נֶעֶרְמוּ מַיִם, נִצְּבוּ כְמוֹ נֵד נֹזְלִים, קָפְאוּ תְהֹמֹת בְּלֶב יָם: אָמַר אוֹיֵב אֶרְדֹּף אַשִּׂיג אֲחַלֵּק שָׁלָל, תִּמְלָאֵמוֹ נַפְשִׁי, אָרִיק חַרְבִּי, תּוֹרִישֵׁמוֹ יָדִי: נָשַׁפְתָּ בְרוּחֲךָ כִּסָּמוֹ יָם, צָלְלוּ כַּעוֹפֶרֶת בְּמַיִם, אַדִּירִים: מִי כָמֹכָה בָּאֵלִם יהוה, מִי כָּמֹכָה נֶאְדָּר בַּקֹּדֶשׁ, נוֹרָא תְהִלֹּת עֹשֵׂה פֶלֶא: נָטִיתָ יְמִינְךָ תִּבְלָעֵמוֹ אָרֶץ: נָחִיתָ בְחַסְדְּךָ עַם זוּ גָּאָלְתָּ, נֵהַלְתָּ בְעָזְּךָ אֶל נְוֵה קָדְשֶׁךָ: שָׁמְעוּ עַמִּים יִרְגָּזוּן, חִיל אָחַז יֹשְׁבֵי פְּלָשֶׁת: אָז נִבְהֲלוּ אַלּוּפֵי אֱדוֹם, אֵילֵי מוֹאָב יֹאחֲזֵמוֹ רָעַד, נָמֹגוּ כָּל יֹשְׁבֵי כְנָעַן: תִּפֹּל עֲלֵיהֶם אֵימָתָה וָפַחַד, בִּגְדֹל זְרוֹעֲךָ יִדְּמוּ כָּאָבֶן, עַד יַעֲבֹר עַמְּךָ, יהוה, עַד יַעֲבֹר עַם זוּ קָנִיתָ: תְּבִאֵמוֹ וְתִטָּעֵמוֹ בְּהַר נַחֲלָתְךָ, מָכוֹן לְשִׁבְתְּךָ פָּעַלְתָּ יהוה, מִקְּדָשׁ, אֲדֹנָי כּוֹנְנוּ יָדֶיךָ: יהוה יִמְלֹךְ לְעֹלָם וָעֶד: יהוה יִמְלֹךְ לְעֹלָם וָעֶד: יהוה מַלְכוּתֵהּ קָאֵם לְעָלַם וּלְעָלְמֵי עָלְמַיָּא. כִּי בָא סוּס פַּרְעֹה בְּרִכְבּוֹ וּבְפָרָשָׁיו בַּיָּם, וַיָּשֶׁב יהוה עֲלֵהֶם אֶת מֵי הַיָּם, וּבְנֵי יִשְׂרָאֵל הָלְכוּ בַיַּבָּשָׁה בְּתוֹךְ הַיָּם: כִּי לַיהוה הַמְּלוּכָה וּמֹשֵׁל בַּגּוֹיִם: וְעָלוּ מוֹשִׁעִים בְּהַר צִיּוֹן לִשְׁפֹּט אֶת הַר עֵשָׂו, וְהָיְתָה לַיהוה הַמְּלוּכָה: וְהָיָה יהוה לְמֶלֶךְ עַל כָּל הָאָרֶץ, בַּיּוֹם הַהוּא יִהְיֶה יהוה אֶחָד וּשְׁמוֹ אֶחָד:","cond":[]},{"kind":"instruction","text":"ברכת \"ישתבח\" יש בה י\"ג שבחים כנגד י\"ג מדות.","cond":[]},{"kind":"text","text":"יִשְׁתַּבַּח שִׁמְךָ לָעַד מַלְכֵּנוּ, הָאֵל הַמֶּלֶךְ הַגָּדוֹל וְהַקָּדוֹשׁ בַּשָּׁמַיִם וּבָאָרֶץ, כִּי לְךָ נָאֶה, יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ לְעוֹלָם וָעֶד:\n(א) שִׁיר (ב) וּשְׁבָחָה, (ג) הַלֵּל (ד) וְזִמְרָה, (ה) עֹז (ו) וּמֶמְשָׁלָה, (ז) נֶצַח, (ח) גְּדֻלָּה (ט) וּגְבוּרָה, (י) תְּהִלָּה (יא) וְתִפְאֶרֶת, (יב) קְדֻשָּׁה (יג) וּמַלְכוּת, בְּרָכוֹת וְהוֹדָאות לְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ, וּמֵעוֹלָם וְעַד עוֹלָם אַתָּה אֵל.\nבָּרוּךְ אַתָּה יהוה, מֶלֶךְ גָּדוֹל וּמְהֻלָּל בַּתִּשְׁבָּחוֹת, אֵל הַהוֹדָאות, אֲדוֹן הַנִּפְלָאוֹת, בּוֹרֵא כָל הַנְּשָׁמוֹת, רִבּוֹן כָּל הַמַּעֲשִׂים, הַבּוֹחֵר בְּשִׁירֵי זִמְרָה, מֶלֶךְ, אֵל, חַי הָעולָמִים. אָמֵן.","cond":[]},{"kind":"header","text":"שיר המעלות","cond":["ayt"]},{"kind":"special","text":"שִׁיר הַמַּעֲלוֹת, מִמַּעֲמַקִּים קְרָאתִיךָ יהוה: אֲדֹנָי, שִׁמְעָה בְקוֹלִי, תִּהְיֶינָה אָזְנֶיךָ קַשֻּׁבוֹת לְקוֹל תַּחֲנוּנָי: אִם עֲוׂנוֹת תִּשְׁמָר יָהּ, אֲדֹנָי מִי יַעֲמֹד: כִּי עִמְּךָ הַסְּלִיחָה לְמַעַן תִּוָּרֵא: קִוִּיתִי יהוה, קִוְּתָה נַפְשִׁי, וְלִדְבָרוֹ הוֹחָלְתִּי: נַפְשִׁי לַאדֹנָי, מִשֹּׁמְרִים לַבֹּקֶר, שֹׁמְרִים לַבֹּקֶר: יַחֵל יִשְׂרָאֵל אֶל יהוה, כִּי עִם יהוה הַחֶסֶד וְהַרְבֵּה עִמּוֹ פְדוּת: וְהוּא יִפְדֶּה אֶת יִשְׂרָאֵל מִכֹּל עֲוֹנֹתָיו:","cond":["ayt"]},{"kind":"instruction","text":"חצי קדיש","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"header","text":"קריאת שמע וברכותיה","cond":[]},{"kind":"instruction","text":"קריאת שמע וברכותיה","cond":[]},{"kind":"instruction","text":"חזן:","cond":[]},{"kind":"text","text":"בָּרְכוּ אֶת יהוה הַמְבֹרָךְ.","cond":[]},{"kind":"instruction","text":"קהל וחזן:","cond":[]},{"kind":"text","text":"בָּרוּךְ יהוה הַמְבֹרָךְ לְעוֹלָם וָעֶד.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, יוֹצֵר אוֹר וּבוֹרֵא חֹשֶׁךְ, עֹשֵׂה שָׁלוֹם וּבוֹרֵא אֶת הַכֹּל.\n\nהַמֵּאִיר לָאָרֶץ וְלַדָּרִים עָלֶיהָ בְּרַחֲמִים, וּבְטוּבו מְחַדֵּשׁ בְּכָל יוֹם תָּמִיד מַעֲשֵׂה בְּרֵאשִׁית. מָה רַבּוּ מַעֲשֶׂיךָ יהוה, כֻּלָּם בְּחָכְמָה עָשִׂיתָ, מָלְאָה הָאָרֶץ קִנְיָנֶךָ: הַמֶּלֶךְ הַמְּרוֹמָם לְבַדּוֹ מֵאָז, הַמְּשֻׁבָּח וְהַמְּפֹאָר וְהַמִּתְנַשֵּׂא מִימוֹת עוֹלָם. אֱלֹהַי עוֹלָם, בְּרַחֲמֶיךָ הָרַבִּים רַחֵם עָלֵינוּ, אֲדוֹן עֻזֵּנוּ, צוּר מִשְׂגַּבֵנוּ, מָגֵן יִשְׁעֵנוּ, מִשְׂגַּב בַּעֲדֵנוּ. אֵל בָּרוּךְ גְּדוֹל דֵּעָה, הֵכִין וּפָעַל זָהֳרֵי חַמָּה, טוֹב יָצַר כָּבוֹד לִשְׁמוֹ, מְאוֹרוֹת נָתַן סְבִיבוֹת עֻזּוֹ, פִּנּוֹת צִבְאוֹת קְדוֹשִׁים, רוֹמְמֵי שַׁדַּי, תָּמִיד מְסַפְּרִים כְּבוֹד אֵל וּקְדֻשָּׁתוֹ. תִּתְבָּרַךְ יהוה אֱלֹהֵינוּ בַּשָּׁמַיִם מִמַּעַל וְעַל הָאָרֶץ מִתַּחַת עַל כָּל שֶׁבַח מַעֲשֵׂה יָדֶיךָ, וְעַל מְאוֹרֵי אוֹר שֶׁיָּצַרְתָּ הֵמָּה יְפָאֲרוּךָ סֶלָה.\n\nתִּתְבָּרַךְ לָנֶצַח צוּרֵנוּ מַלְכֵּנוּ וְגוֹאֲלֵנוּ בּוֹרֵא קְדוֹשִׁים, יִשְׁתַּבַּח שִׁמְךָ לָעַד מַלְכֵּנוּ יוֹצֵר מְשָׁרְתִים, וַאֲשֶׁר מְשָׁרְתָיו כֻּלָּם עוֹמְדִים בְּרוּם עוֹלָם וּמַשְׁמִיעִים בְּיִרְאָה יַחַד בְּקוֹל דִּבְרֵי אֱלֹהִים חַיִּים וּמֶלֶךְ עוֹלָם, כֻּלָּם אֲהוּבִים, כֻּלָּם בְּרוּרִים, כֻּלָּם גִּבּוֹרִים, כֻּלָּם קְדוֹשִׁים, כֻּלָּם עוֹשִׂים בְּאֵימָה וּבְיִרְאָה רְצוֹן קוֹנֵיהֶם, וְכֻלָּם פּוֹתְחִים אֶת פִּיהֶם בִּקְדֻשָּׁה וּבְטָהֳרָה, בְּשִׁירָה וּבְזִמְרָה, וּמְבָרְכִין וּמְשָׁבְּחִין וּמְפָאֲרִין וּמַקְדִּישִׁין וּמַעֲרִיצִין וּמַמְלִיכִין אֶת שֵׁם הָאֵל הַמֶּלֶךְ הַגָּדוֹל הַגִּבּור וְהַנּוֹרָא קָדוֹשׁ הוּא, וְכֻלָּם מְקַבְּלִים עֲלֵיהֶם עֹל מַלְכוּת שָׁמַיִם זֶה מִזֶּה, וְנוֹתְנִים רְשׁוּת זֶה לָזֶה לְהַקְדִּישׁ לְיוֹצְרָם בְּנַחַת רוּחַ, בְּשָׂפָה בְרוּרָה וּבִנְעִימָה, קְדֻשָּׁה כֻּלָּם כְּאֶחָד עוֹנִים בְּאֵימָה, וְאוֹמְרִים בְּיִרְאָה:\n\nקָדוֹשׁ, קָדוֹשׁ, קָדוֹשׁ יהוה צְבָאוֹת, מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ:\n\nוְהָאוֹפַנִּים וְחַיּות הַקֹדֶשׁ בְּרַעַשׁ גָּדוֹל מִתְנַשְּׂאִים לְעֻמַּת הַשְּׂרָפִים, לְעֻמַּתָם מְשַׁבְּחִים וְאוֹמְרִים:\n\nבָּרוּךְ כְּבוֹד יהוה מִמְּקוֹמוֹ:\n\nלָאֵל בָּרוּךְ, נְעִימוּת יִתְּנוּ, לַמֶּלֶךְ אֵל חַי וְקַיָּם, זְמִירוֹת יֹאמְרוּ וְתִשְׁבָּחוֹת יַשְׁמִיעוּ, כִּי הוּא לְבַדּוֹ מָרוֹם וְקָדוֹשׁ, פּוֹעֵל גְּבוּרוֹת, עוֹשֶׂה חֲדָשׁוֹת, בַּעַל מִלְחָמוֹת, זוֹרֵעַ צְדָקוֹת, מַצְמִיחַ יְשׁוּעוֹת, בּוֹרֵא רְפוּאוֹת, נוֹרָא תְהִלּוֹת, אֲדוֹן הַנִּפְלָאוֹת, הַמְחַדֵּשׁ בְּטוּבו בְּכָל יוֹם תָּמִיד מַעֲשֵׂה בְרֵאשִׁית, כָּאָמוּר: לְעֹשֵׂה אוֹרִים גְּדֹלִים כִּי לְעוֹלָם חַסְדּוֹ: בָּרוּךְ אַתָּה יהוה, יוֹצֵר הַמְּאוֹרוֹת.\n\n\nאַהֲבַת עוֹלָם אֲהַבְתָּנוּ יהוה אֱלֹהֵינוּ, חֶמְלָה גְּדוֹלָה וִיתֵרָה חָמַלְתָּ עָלֵינוּ. אָבִינוּ מַלְכֵּנוּ, בַּעֲבוּר שִׁמְךָ הַגָּדוֹל וּבַעֲבוּר אֲבוֹתֵינוּ שֶׁבָּטְחוּ בָךְ וַתְּלַמְּדֵמוֹ חֻקֵּי חַיִּים לַעֲשׂוֹת רְצונְךָ בְּלֵבָב שָׁלֵם, כֵּן תְּחָנֵּנוּ אָבִינוּ, אָב הָרַחֲמָן. הַמְרַחֵם, רַחֵם נָא עָלֵינוּ, וְתֵן בְּלִבֵּנוּ בִינָה לְהָבִין, לְהַשְׂכִּיל, לִשְׁמֹעַ, לִלְמֹד וּלְלַמֵּד, לִשְׁמֹר וְלַעֲשׂוֹת וּלְקַיֵּם אֶת כָּל דִּבְרֵי תַּלְמוּד תוֹרָתְךָ בְּאַהֲבָה. וְהָאֵר עֵינֵינוּ בְּתוֹרָתֶךָ וְדַבֵּק לִבֵּנוּ בְמִצְוׂתֶיךָ, וְיַחֵד לְבָבֵנוּ לְאַהֲבָה וּלְיִרְאָה אֶת שְׁמֶךָ. לֹא נֵבושׁ וְלֹא נִכָּלֵם וְלֹא נִכָּשֵׁל לְעוֹלָם וָעֶד. כִּי בְשֵׁם קָדְשְׁךָ הַגָּדוֹל הַגִּבּור וְהַנּוֹרָא בָּטָחְנוּ, נָגִילָה וְנִשְׂמְחָה בִּישׁוּעָתֶךָ. וְרַחֲמֶיךָ יהוה אֱלֹהֵינוּ וַחֲסָדֶיךָ הָרַבִּים, אַל יַעַזְבוּנוּ נֶצַח סֶלָה וָעֶד. מַהֵר וְהַבֵא עָלֵינוּ בְּרָכָה וְשָׁלוֹם מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ, וּשְׁבֹר עֹל הַגּוֹיִם מֵעַל צַוָּארֵנוּ, וְהוֹלִיכֵנוּ מְהֵרָה קוֹמְמִיּוּת לְאַרְצֵנוּ, כִּי אֵל פּוֹעֵל יְשׁוּעוֹת אַתָּה, וּבָנוּ בָחַרְתָּ מִכָּל עַם וְלָשׁוֹן, וְקֵרַבְתָּנוּ מַלְכֵּנוּ לְשִׁמְךָ הַגָּדוֹל בְּאַהֲבָה, לְהוֹדוֹת לָךְ וּלְיַחֶדְךָ, לְיִרְאָה וּלְאַהֲבָה אֶת שְׁמֶךָ. בָּרוּךְ אַתָּה יהוה, הַבּוֹחֵר בְּעַמּוֹ יִשְׂרָאֵל בְּאַהֲבָה.","cond":[]},{"kind":"header","text":"קריאת שמע","cond":[]},{"kind":"instruction","text":"קריאת שמע","cond":[]},{"kind":"text","text":"שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:","cond":[]},{"kind":"instruction","text":"בלחש:","cond":[]},{"kind":"text","text":"בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד.\n\nוְאָהַבְתָּ אֵת יהוה אֱלֹהֶיךָ, בְּכָל לְבָבְךָ וּבְכָל נַפְשְׁךָ וּבְכָל מְאֹדֶךָ: וְהָיוּ הַדְּבָרִים הָאֵלֶּה אֲשֶׁר אָנֹכִי מְצַוְּךָ הַיּוֹם, עַל לְבָבֶךָ: וְשִׁנַּנְתָּם לְבָנֶיךָ וְדִבַּרְתָּ בָּם, בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ: וּקְשַׁרְתָּם לְאוֹת עַל יָדֶךָ, וְהָיוּ לְטֹטָפֹת בֵּין עֵינֶיךָ: וּכְתַבְתָּם עַל מְזֻזוֹת בֵּיתֶךָ וּבִשְׁעָרֶיךָ:","cond":[]},{"kind":"text","text":"וְהָיָה אִם שָׁמֹעַ תִּשְׁמְעוּ אֶל מִצְוׂתַי, אֲשֶׁר אָנֹכִי מְצַוֶּה אֶתְכֶם הַיּוֹם, לְאַהֲבָה אֶת יהוה אֱלֹהֵיכֶם וּלְעָבְדוֹ, בְּכָל לְבַבְכֶם וּבְכָל נַפְשְׁכֶם: וְנָתַתִּי מְטַר אַרְצְכֶם בְּעִתּוֹ, יוֹרֶה וּמַלְקוֹשׁ, וְאָסַפְתָּ דְגָנֶךָ וְתִירֹשְׁךָ וְיִצְהָרֶךָ: וְנָתַתִּי עֵשֶׂב בְּשָׂדְךָ לִבְהֶמְתֶּךָ, וְאָכַלְתָּ וְשָׂבָעְתָּ: הִשָּׁמְרוּ לָכֶם פֶּן יִפְתֶּה לְבַבְכֶם, וְסַרְתֶּם וַעֲבַדְתֶּם אֱלֹהִים אֲחֵרִים וְהִשְׁתַּחֲוִיתֶם לָהֶם: וְחָרָה אַף יהוה בָּכֶם, וְעָצַר אֶת הַשָּׁמַיִם וְלֹא יִהְיֶה מָטָר, וְהָאֲדָמָה לֹא תִתֵּן אֶת יְבוּלָהּ, וַאֲבַדְתֶּם מְהֵרָה מֵעַל הָאָרֶץ הַטֹּבָה אֲשֶׁר יהוה נֹתֵן לָכֶם: וְשַׂמְתֶּם אֶת דְּבָרַי אֵלֶּה עַל לְבַבְכֶם וְעַל נַפְשְׁכֶם, וּקְשַׁרְתֶּם אֹתָם לְאוֹת עַל יֶדְכֶם וְהָיוּ לְטוֹטָפֹת בֵּין עֵינֵיכֶם: וְלִמַּדְתֶּם אֹתָם אֶת בְּנֵיכֶם לְדַבֵּר בָּם, בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ: וּכְתַבְתָּם עַל מְזוּזוֹת בֵּיתֶךָ וּבִשְׁעָרֶיךָ: לְמַעַן יִרְבּוּ יְמֵיכֶם וִימֵי בְנֵיכֶם עַל הָאֲדָמָה אֲשֶׁר נִשְׁבַּע יהוה לַאֲבֹתֵיכֶם לָתֵת לָהֶם, כִּימֵי הַשָּׁמַיִם עַל הָאָרֶץ:","cond":[]},{"kind":"text","text":"וַיֹּאמֶר יהוה אֶל מֹשֶׁה לֵּאמֹר: דַּבֵּר אֶל בְּנֵי יִשְׂרָאֵל וְאָמַרְתָּ אֲלֵהֶם, וְעָשׂוּ לָהֶם צִיצִת עַל כַּנְפֵי בִגְדֵיהֶם לְדֹרֹתָם, וְנָתְנוּ עַל צִיצִת הַכָּנָף פְּתִיל תְּכֵלֶת: וְהָיָה לָכֶם לְצִיצִת, וּרְאִיתֶם אֹתוֹ, וּזְכַרְתֶּם אֶת כָּל מִצְוׂת יהוה וַעֲשִׂיתֶם אֹתָם, וְלֹא תָתֻרוּ אַחֲרֵי לְבַבְכֶם וְאַחֲרֵי עֵינֵיכֶם אֲשֶׁר אַתֶּם זֹנִים אַחֲרֵיהֶם: לְמַעַן תִּזְכְּרוּ וַעֲשִׂיתֶם אֶת כָּל מִצְוׂתָי, וִהְיִיתֶם קְדֹשִׁים לֵאלֹהֵיכֶם: אֲנִי יהוה אֱלֹהֵיכֶם אֲשֶׁר הוֹצֵאתִי אֶתְכֶם מֵאֶרֶץ מִצְרַיִם, לִהְיוֹת לָכֶם לֵאלֹהִים, אֲנִי יהוה אֱלֹהֵיכֶם:","cond":[]},{"kind":"text","text":"אֱמֶת","cond":[]},{"kind":"instruction","text":"יסיים \"אני ה' אלהיכם אמת\" עם שליח הציבור יחד, ומילת \"אמת\" יאמרו אותה הקהל בקול רם, ואחר כך ישתוק וישמע משליח הציבור כשחוזר ואומר \"ה' אלהיכם אמת\" ויכוון לצאת ידי חובה באמירתו של שליח הציבור, ושליח הציבור יכוון אף הוא להוציא את הקהל ידי חובה. והקורא קריאת שמע ביחידות או שלא הספיק לסיים עם שליח הציבור, יחזור לומר \"ה' אלהיכם אמת\" כדי להשלים לרמ\"ח תיבות.\n\nשליח הציבור חוזר ואומר:","cond":[]},{"kind":"text","text":"יהוה אֱלֹהֵיכֶם: אֱמֶת","cond":[]},{"kind":"instruction","text":"הברכות שאחרי קריאת שמע","cond":[]},{"kind":"text","text":"וְיַצִּיב, וְנָכוֹן, וְקַיָּם, וְיָשָׁר, וְנֶאֱמָן, וְאָהוּב, וְחָבִיב, וְנֶחְמָד, וְנָעִים, וְנוֹרָא, וְאַדִּיר, וּמְתֻקָּן, וּמְקֻבָּל, וְטוֹב, וְיָפֶה, הַדָּבָר הַזֶּה עָלֵינוּ לְעוֹלָם וָעֶד. \nאֱמֶת, אֱלֹהֵי עוֹלָם מַלְכֵּנוּ צוּר יַעֲקֹב מָגֵן יִשְׁעֵנוּ, לְדֹר וָדֹר הוּא קַיָּם, וּשְׁמוֹ קַיָּם, וְכִסְאוֹ נָכוֹן, וּמַלְכוּתו וֶאֱמוּנָתו לָעַד קַיֶּמֶת, וּדְבָרָיו חַיִּים וְקַיָּמִים, וְנֶאֱמָנִים וְנֶחֱמָדִים לָעַד וּלְעוֹלְמֵי עוֹלָמִים. עַל אֲבוֹתֵינוּ, עָלֵינוּ וְעַל בָּנֵינוּ וְעַל דּוֹרוֹתֵינוּ וְעַל כָּל דּוֹרוֹת זֶרַע יִשְׂרָאֵל עֲבָדֶיךָ. עַל הָרִאשׁוֹנִים וְעַל הָאַחֲרוֹנִים דָּבָר טוֹב וְקַיָּם בֶּאֱמֶת וֶאֱמוּנָה חֹק וְלֹא יַעֲבוֹר. אֱמֶת שֶׁאַתָּה הוּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מַלְכֵּנוּ מֶלֶךְ אֲבוֹתֵינוּ, גּוֹאֲלֵנוּ גּוֹאֵל אֲבוֹתֵינוּ, יוֹצְרֵנוּ צוּר יְשׁוּעָתֵנוּ, פּוֹדֵנוּ וּמַצִּילֵנוּ מֵעוֹלָם הוּא שְׁמֶךָ, וְאֵין לָנוּ עוֹד אֱלֹהִים זוּלָתְךָ סֶלָה.\n\nעֶזְרַת אֲבוֹתֵינוּ אַתָּה הוּא מֵעוֹלָם, מָגֵן וּמושִׁיעַ לָהֶם וְלִבְנֵיהֶם אַחֲרֵיהֶם בְּכָל דֹּר וָדֹר, בְּרוּם עוֹלָם מוֹשָׁבֶךָ, וּמִשְׁפָּטֶיךָ, וְצִדְקָתְךָ עַד אַפְסֵי אָרֶץ, אֱמֶת, אַשְׁרֵי אִישׁ שֶׁיִּשְׁמַע לְמִצְוׂתֶיךָ, וְתוֹרָתְךָ וּדְבָרְךָ יָשִׂים עַל לִבּוֹ. אֱמֶת שֶׁאַתָּה הוּא אֲדוֹן לְעַמְּךָ וּמֶלֶךְ גִּבּוֹר לָרִיב רִיבָם לְאָבוֹת וּבָנִים, אֱמֶת אַתָּה הוּא רִאשׁוֹן וְאַתָּה הוּא אַחֲרוֹן וּמִבַּלְעָדֶיךָ אֵין לָנוּ מֶלֶךְ גּוֹאֵל וּמוֹשִׁיעַ. אֱמֶת מִמִּצְרַיִם גְּאַלְתָּנוּ יהוה אֱלֹהֵינוּ, מִבֵּית עֲבָדִים פְּדִיתָנוּ, כָּל בְּכוֹרֵיהֶם הָרַגְתָּ, וּבְכוֹרְךָ יִשְׂרָאֵל גָּאַלְתָּ, וְיָם סוּף לָהֶם בָּקַעְתָּ, וְזֵדִים טִבַּעְתָּ, וִידִידִים עָבְרוּ יָם. וַיְכַסּוּ מַיִם צָרֵיהֶם אֶחָד מֵהֶם לֹא נוֹתַר. עַל זֹאת שִׁבְּחוּ אֲהוּבִים, וְרוֹמְמוּ לָאֵל, וְנָתְנוּ יְדִידִים זְמִירוֹת שִׁירוֹת וְתִשְׁבָּחוֹת, בְּרָכוֹת וְהוֹדָאוֹת לַמֶּלֶךְ אֵל חַי וְקַיָּם, רָם וְנִשָּׂא, גָּדוֹל וְנוֹרָא, מַשְׁפִּיל גֵּאִים עֲדֵי אָרֶץ, מַגְבִּיהַּ שְׁפָלִים עַד מָרוֹם, מוֹצִיא אֲסִירִים, פּוֹדֶה עֲנָוִים, עוֹזֵר דַּלִּים, הָעוֹנֶה לְעַמּוֹ יִשְׂרָאֵל בְּעֵת שַׁוְּעָם אֵלָיו. תְהִלּוֹת לָאֵל עֶלְיוֹן גּוֹאֲלָם, בָּרוּךְ הוּא וּמְבוֹרָךְ, מֹשֶׁה וּבְנֵי יִשְׂרָאֵל לְךָ עָנוּ שִׁירָה בְשִׂמְחָה רַבָּה, וְאָמְרוּ כֻלָּם:\n\nמִי כָמֹכָה בָּאֵלִם יהוה, מִי כָּמֹכָה נֶאְדָּר בַּקֹּדֶשׁ, נוֹרָא תְהִלֹּת עֹשֵׂה פֶלֶא:\n\nשִׁירָה חֲדָשָׁה שִׁבְּחוּ גְאוּלִים לְשִׁמְךָ הַגָּדוֹל עַל שְׂפַת הַיָּם, יַחַד כֻּלָם הוֹדוּ וְהִמְלִיכוּ וְאָמְרוּ:\n\nיהוה יִמְלֹךְ לְעֹלָם וָעֶד:\n\nוְנֶאֱמַר: גֹּאֲלֵנוּ יהוה צְבָאוֹת שְׁמוֹ, קְדוֹשׁ יִשְׂרָאֵל: בָּרוּךְ אַתָּה יהוה, גָּאַל יִשְׂרָאֵל.","cond":[]},{"kind":"header","text":"עמידה","cond":[]},{"kind":"instruction","text":"תפילת עמידה","cond":[]},{"kind":"text","text":"אֲדֹנָי, שְׂפָתַי תִּפְתָּח, וּפִי יַגִּיד תְּהִלָּתֶךָ:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יְהֹוָה, אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק וֵאלֹהֵי יַעֲקֹב, הָאֵל הַגָּדוֹל, הַגִּבּוֹר וְהַנּוֹרָא, אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, קוֹנֵה הַכֹּל וְזוֹכֵר חַסְדֵי אָבוֹת וּמֵבִיא גּוֹאֵל לִבְנֵי בְנֵיהֶם לְמַעַן שְׁמוֹ בְּאַהֲבָה.","cond":[]},{"kind":"special","text":"זָכְרֵנוּ לְחַיִּים, מֶלֶךְ חָפֵץ בַּחַיִּים, כָּתְבֵנוּ בְּסֵפֶר חַיִּים, לְמַעַנְךָ אֱלֹהִים חַיִּים.","cond":["ayt"]},{"kind":"text","text":"מֶלֶךְ עוֹזֵר וּמוֹשִׁיעַ וּמָגֵן. בָּרוּךְ אַתָּה יַהַוַהַ, מָגֵן אַבְרָהָם.","cond":[]},{"kind":"text","text":"אַתָּה גִּבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֵּה מֵתִים אַתָּה, רַב לְהוֹשִׁיעַ,","cond":[]},{"kind":"summer","text":"מוֹרִיד הַטָּל,","cond":["summerTal"]},{"kind":"winter","text":"מַשִּׁיב הָרוּחַ וּמוֹרִיד הַגֶּשֶׁם,","cond":["winterTal"]},{"kind":"text","text":"מְכַלְכֵּל חַיִּים בְּחֶסֶד, מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים, סוֹמֵךְ נוֹפְלִים וְרוֹפֵא חוֹלִים, וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמוּנָתוֹ לִישֵׁנֵי עָפָר. מי כָמוֹךָ בַּעַל גְּבוּרוֹת וּמִי דוֹמֶה לָךְ, מֶלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִיחַ יְשׁוּעָה.","cond":[]},{"kind":"special","text":"מִי כָמוֹךָ אַב הָרַחֲמָן, זוֹכֵר יְצוּרָיו בְּרַחֲמִים לְחַיִּים.","cond":["ayt"]},{"kind":"text","text":"וְנֶאֱמָן אַתָּה לְהַחֲיוֹת מֵתִים. בָּרוּךְ אַתָּה יֵהֵוֵהֵ, מְחַיֵּה הַמֵּתִים.","cond":[]},{"kind":"text","text":"אַתָּה קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ, וּקְדוֹשִׁים בְּכָל-יוֹם יְהַלְלוּךָ סֶּלָה.","cond":[]},{"kind":"special","text":"בָּרוּךְ אַתָּה יֹהֵוָה, הַמֶּלֶךְ הַקָּדוֹשׁ.","cond":["ayt"]},{"kind":"text","text":"בּרוּךְ אַתָּה יֹהֵוָה, הָאֵל הַקָּדוֹשׁ.","cond":["noayt"]},{"kind":"text","text":"אַתָּה חוֹנֵן לְאָדָם דַּעַת וּמְלַמֵּד לֶאֱנוֹשׁ בִּינָה. וְחָנֵּנוּ מֵאִתְּךָ חָכְמָה בִּינָה וָדָעַת. בָּרוּךְ אַתָּה יַהַוַהַ חוֹנֵן הַדָּעַת.","cond":[]},{"kind":"text","text":"הֲשִׁיבֵנוּ אָבִינוּ לְתוֹרָתֶךָ, וְקָרְבֵנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶךָ, וְהַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ. בָּרוּךְ אַתָּה יֵהֵוֵהֵ, הָרוֹצֶה בִּתְשׁוּבָה.","cond":[]},{"kind":"text","text":"סְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחֹל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ, כִּי אֵל טוֹב וְסַלָּח אָתָּה. בָּרוּךְ אַתָּה יֶהֶוֶהֶ, חַנּוּן הַמַּרְבֶּה לִסְלֹחַ.","cond":[]},{"kind":"text","text":"רְאֵה נָא בְעָנְיֵנוּ וְרִיבָה רִיבֵנוּ, וּמַהֵר לְגָאֳלֵנוּ גְאֻלָּה שְׁלֵמָה לְמַעַן שְׁמֶךָ, כִּי אֵל גּוֹאֵל חָזָק אָתָּה. בָּרוּךְ אַתָּה יְהְוְהְ, גוֹאֵל יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"רְפָאֵנוּ יְהֹוָה וְנֵרָפֵא, הוֹשִׁיעֵנוּ וְנִוָּשֵׁעָה כִּי תְהִלָּתֵנוּ אָתָּה, וְהַעֲלֵה אֲרוּכָה וּמַרְפֵּא לְכָל-תַּחֲלוּאֵינוּ וּלְכָל-מַכְאוֹבֵינוּ וּלְכָל-מַכּוֹתֵינוּ.","cond":[]},{"kind":"special","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁתִּשְׁלַח מְהֵרָה רְפוּאָה שְׁלֵמָה מִן הַשָּׁמַיִם, רְפוּאַת הַנֶּפֶשׁ וּרְפוּאַת הַגּוּף לַחוֹלֶה (לנקבה: לַחוֹלָה, לרבים: לַחוֹלִים, לרבות: לַחוֹלוֹת):\n:=:=\nבְּתוֹךְ שְׁאָר חוֹלֵי יִשְׂרָאֵל.","cond":["doctor"]},{"kind":"text","text":"כִּי אֵל רוֹפֵא רַחֲמָן וְנֶאֱמָן אָתָּה. בָּרוּךְ אַתָּה יֹהֹוׂהֹ, רוֹפֵא חוֹלֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"summer","text":"בָּרְכֵנוּ יְהֹוָה אֱלֹהֵינוּ בְּכָל מַעֲשֵׂי יָדֵינוּ, וּבָרֵךְ שְׁנָתֵנוּ בְּטַלְלֵי רָצוֹן בְּרָכָה וּנְדָבָה, וּתְהִי אַחֲרִיתָהּ חַיִּים וְשָׂבָע וְשָׁלוֹם כַּשָּׁנִים הַטּוֹבוֹת לִבְרָכָה. כִּי אֵל טוֹב וּמֵטִיב אַתָּה וּמְבָרֵךְ הַשָּׁנִים. בָּרוּךְ אַתָּה יִהִוִהִ, מְבָרֵךְ הַשָּׁנִים.","cond":["summerBracha"]},{"kind":"winter","text":"בָּרֵךְ עָלֵינוּ יְהֹוָה אֱלֹהֵינוּ אֶת הַשָּׁנָה הַזֹּאת וְאֶת כָּל מִינֵי תְּבוּאָתָהּ לְטוֹבָה, וְתֵן טַל וּמָטָר לִבְרָכָה עַל כָּל פְּנֵי הָאֲדָמָה, וְרַוֵּה פְּנֵי תֵבֵל וְשַׂבַּע אֶת הָעוֹלָם כֻּלּוֹ מִטּוּבָךְ, וּמַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ וּמֵעֹשֶׁר מַתְּנוֹת יָדֶיךָ. שָׁמְרָה וְהַצִּילָה שָׁנָה זוֹ מִכָּל דָּבָר רָע וּמִכָּל מִינֵי מַשְׁחִית וּמִכָּל מִינֵי פֻרְעָנוּת, וַעֲשֵׂה לָהּ תִּקְוָה טוֹבה וְאַחֲרִית שָׁלוֹם. חוּס וְרַחֵם עָלֶיהָ וְעַל כָּל תְּבוּאָתָהּ וּפֵירוֹתֶיהָ, וּבָרְכָהּ בְּגִשְׁמֵי רָצוֹן בְּרָכָה וּנְדָבָה, וּתְהִי אַחֲרִיתָהּ חַיִּים וְשָׂבָע וְשָׁלוֹם כַּשָּׁנִים הַטּוֹבוֹת לִבְרָכָה. כִּי אֵל טוֹב וּמֵטִיב אַתָּה וּמְבָרֵךְ הַשָּׁנִים. בָּרוּךְ אַתָּה יִהִוִהִ, מְבָרֵךְ הַשָּׁנִים.","cond":["winterBracha"]},{"kind":"text","text":"תְּקַע בְּשׁוֹפָר גָּדוֹל לְחֵרוּתֵנוּ, וְשָׂא נֵס לְקַבֵּץ גָּלֻיּוֹתֵינוּ, וְקַבְּצֵנוּ יַחַד מֵאַרְבַּע כַּנפוֹת הָאָרֶץ לְאַרְצֵנוּ. בָּרוּךְ אַתָּה יֻהֻוֻהֻ, מְקַבֵּץ נִדְחֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"הָשִׁיבָה שׁוֹפְטֵינוּ כְּבָרִאשׁוֹנָה, וְיוֹעֲצֵינוּ כְּבַתְּחִלָּה, וְהָסֵר מִמֶּנוּ יָגוֹן וַאֲנָחָה, וּמְלֹךְ עָלֵינוּ מְהֵרָה אַתָּה יְהֹוָה לְבַדְּךָ, בְּחֶסֶד וּבְרַחֲמִים, בְּצֶדֶק וּבְמִשְׁפָּט.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יוּהוּווּהוּ, מֶלֶךְ אוֹהֵב צְדָקָה וּמִשְׁפָּט.","cond":["noAyt"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יוּהוּווּהוּ, הַמֶּלֶךְ הַמִּשְׁפָּט.","cond":["ayt"]},{"kind":"text","text":"לַמִּינִים וְלַמַּלְשִׁינִים אַל תְּהִי תִקְוָה, וְכָל הַזֵּדִים כְּרֶגַע יֹאבֵדוּ, וְכָל אוֹיְבֶיךָ וְכָל שׂוֹנְאֶיךָ מְהֵרָה יִכָּרֵתוּ, וּמַלְכוּת הָרִשְׁעָה מְהֵרָה תְעַקֵּר וּתְשַׁבֵּר וּתְכַלֵּם וְתַכְנִיעֵם בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יָהָוָהָ, שׁוֹבֵר אוֹיְבִים וּמַכְנִיעַ זֵדִים.","cond":[]},{"kind":"text","text":"עַל הַצַּדִּיקִים וְעַל הַחֲסִידִים וְעַל שְׁאֵרִית עַמְּךָ בֵּית יִשְׂרָאֵל וְעַל זִקְנֵיהֶם וְעַל פְּלֵטַת בֵּית סוֹפְרֵיהֶם וְעַל גֵּרֵי הַצֶּדֶק וְעָלֵינוּ, יֶהֱמוּ נָא רַחֲמֶיךָ יְהֹוָה אֱלֹהֵינוּ, וְתֵן שָׂכָר טוֹב לְכָל הַבּוֹטְחִים בְּשִׁמְךָ בֶאֱמֶת, וְשִׂים חֶלְקֵנוּ עִמָּהֶם, וּלְעוֹלָם לֹא נֵבוֹשׁ כִּי בְךָ בָטַחְנוּ, וְעַל חַסְדְּךָ הַגָּדוֹל בֶּאֱמֶת נִשְׁעָנְנוּ. בָּרוּךְ אַתָּה יוּהוּווּהוּ, מִשְׁעָן וּמִבְטָח לַצַּדִּיקִים.","cond":[]},{"kind":"text","text":"תִּשְׁכּוֹן בְּתוֹךְ יְרוּשָׁלַיִם עִירְךָ כַּאֲשֶׁר דִּבַּרְתָּ, וְכִסֵּא דָוִד עַבְדְּךָ מְהֵרָה בְתוֹכָהּ תָּכִין, וּבְנֵה אוֹתָהּ בִּנְיַן עוֹלָם בִּמְהֵרָה בְיָמֵינוּ.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יֻהֻוֻהֻ, בּוֹנֵה יְרוּשָׁלָיִם.","cond":["noTishaaBeav"]},{"kind":"special","text":"נַחֵם יהוה אֱלֹהֵינוּ אֶת אֲבֵלֵי צִיּוֹן וְאֶת אֲבֵלֵי יְרוּשָׁלַיִם, וְאֶת הָעִיר הַחֲרֵבָה וְהַבְּזוּיָה וְהַשוֹמֵמָה, מִבְּלִי בָנֶיהָ הִיא יוֹשֶׁבֶת, וְרֹאשָׁהּ חָפוּי כְּאִשָּׁה עֲקָרָה שֶׁלֹּא יָלָדָה. וַיְבַלְּעוּהָ לִגְיוֹנִים וַיִּירָשׁוּהָ, וַיַטִּילוּ אֶת עַמְּךָ יִשְׂרָאֵל לַחֶרֶב, וַיַּהַרְגוּ בְזָדוֹן חֲסִידָי עֶלְיוֹן. עַל כֵּן צִיּוֹן בְּמֶרֶר תִּבְכֶּה וִירוּשָׁלַיִם תִּתֵּן קוֹלָהּ. לִבִּי לִבִּי עַל חַלְלֵיהֶם, מֵעַי מֵעַי עַל הֲרוּגֵיהֶם. כִּי אַתָּה יהוה בָּאֵשׁ הִצַּתָּהּ, וּבָאֵשׁ אַתָּה עָתִיד לִבְנוֹתָהּ, כַּכָּתוּב: וַאֲנִי אֶהְיֶה לָהּ נְאֻם יְהוה חוֹמַת אֵשׁ סָבִיב, וּלְכָבוֹד אֶהְיֶה בְתוֹכָהּ: בָּרוּךְ אַתָּה יהוה, מְנַחֵם צִיּוֹן בְּבִנְיַן יְרוּשָׁלַיִם.","cond":["tishaaBeav"]},{"kind":"text","text":"אֶת צֶמַח דָּוִד עַבְדְּךָ מְהֵרָה תַצְמִיחַ, וְקַרְנוֹ תָרוּם בִּישׁוּעָתֶךָ. כִּי לִישׁוּעָתְךָ קִוִּינוּ וְצִפִּינוּ כָּל הַיּוֹם. בָּרוּךְ אַתָּה יִהִוִהִ, מַצְמִיחַ קֶרֶן יְשׁוּעָה.","cond":[]},{"kind":"text","text":"שְׁמַע קוֹלֵנוּ יְהֹוָה אֱלֹהֵינוּ, אָב הָרַחֲמָן רַחֵם עָלֵינוּ, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ, כִּי אֵל שׁוֹמֵעַ תְּפִלּוֹת וְתַחֲנוּנִים אָתָּה, וּמִלְּפָנֶיךָ מַלְכֵּנוּ, רֵיקָם אַל תְּשִׁיבֵנוּ. חָנֵּנוּ וַעֲנֵנוּ וּשְׁמַע תְּפִלָּתֵנוּ.","cond":[]},{"kind":"instruction","text":"בתענית ציבור יאמר היחיד \"עננו\".","cond":["taanit"]},{"kind":"special","text":"עֲנֵנוּ אָבִינוּ עֲנֵנוּ בְּיוֹם צוֹם הַתַּעֲנִית הַזֶּה, כִּי בְצָרָה גְדוֹלָה אֲנָחְנוּ. אַל תֵּפֶן לְרִשְׁעֵנוּ, וְאַל תִּתְעַלַּם מַלְכֵּנוּ מִבַּקָּשָׁתֵנוּ, הֱיֵה נָא קָרוֹב לְשַׁוְעָתֵנוּ. טֶרֶם נִקְרָא אֵלֶיךָ אַתָּה תַעֲנֶה, נְדַבֵּר וְאַתָּה תִשְׁמַע, כַּדָּבָר שֶׁנֶּאֱמַר: וְהָיָה טֶרֶם יִקְרָאוּ וַאֲנִי אֶעֱנֶה, עוֹד הֵם מְדַבְּרִים וַאֲנִי אֶשְׁמָע: כִּי אַתָּה יהוה פּוֹדֶה וּמַצִּיל וְעוֹנֶה וּמְרַחֵם בְּכָל עֵת צָרָה וְצוּקָה.","cond":["taanit"]},{"kind":"text","text":"כִּי אַתָּה שׁוֹמֵעַ תְּפִלַּת כָּל פֶּה. בָּרוּךְ אַתָּה יהוה, שׁוֹמֵעַ תְּפִלָּה.","cond":[]},{"kind":"text","text":"רְצֵה יְהֹוָה אֱלֹהֵינוּ בְּעַמְּךָ יִשְׂרָאֵל, וּלִתְפִלָּתָם שְׁעֵה, וְהָשֵׁב הָעֲבוֹדָה לִדְבִיר בֵּיתֶךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם מְהֵרָה בְאַהֲבָה תְּקַבֵּל בְּרָצוֹן, וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּךָ.","cond":[]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, זִכְרוֹן יְרוּשָׁלַיִם עִירָךְ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן לְחֶסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["rh"]},{"kind":"special","text":"רֹאשׁ הַחֹדֶשׁ הַזֶּה,","cond":["rh"]},{"kind":"special","text":"לְרַחֵם בּוֹ עָלֵינוּ וּלְהוֹשִׁיעֵנוּ. זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. בִּדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וַחֲמוֹל וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["rh"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, זִכְרוֹן יְרוּשָׁלַיִם עִירָךְ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן לְחֶסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["sucot"]},{"kind":"special","text":"חַג הַסֻּכּוֹת הַזֶּה, בְּיוֹם מִקְרָא קֹדֶשׁ הַזֶּה,","cond":["sucot"]},{"kind":"special","text":"לְרַחֵם בּוֹ עָלֵינוּ וּלְהוֹשִׁיעֵנוּ. זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. בִּדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וַחֲמוֹל וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["sucot"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, זִכְרוֹן יְרוּשָׁלַיִם עִירָךְ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן לְחֶסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["pesach"]},{"kind":"special","text":"חַג הַמַּצּוֹת הַזֶּה, בְּיוֹם מִקְרָא קֹדֶשׁ הַזֶּה,","cond":["pesach"]},{"kind":"special","text":"לְרַחֵם בּוֹ עָלֵינוּ וּלְהוֹשִׁיעֵנוּ. זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. בִּדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וַחֲמוֹל וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["pesach"]},{"kind":"text","text":"וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים תַּחְפֹּץ בָּנוּ וְתִרְצֵנוּ, וְתֶחֱזֶינָה עֵינֵינוּ בְּשׁוּבְךָ לְצִיּוֹן בְּרַחֲמִים. בָּרוּךְ אַתָּה יִהִוִהִ, הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן.","cond":[]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שֶׁאַתָּה הוּא יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ לְעוֹלָם וָעֶד, צוּרֵנוּ צוּר חַיֵּינוּ וּמָגֵן יִשְׁעֵנוּ אַתָּה הוּא לְדֹר וָדֹר. נוֹדֶה לְּךָ וּנְסַפֵּר תְּהִלָּתֶךָ, עַל חַיֵּינוּ הַמְּסוּרִים בְּיָדֶךָ, וְעַל נִשְׁמוֹתֵינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּיךָ שֶׁבְּכָל יוֹם עִמָּנוּ, וְעַל נִפְלְאוֹתֶיךָ וְטוֹבוֹתֶיךָ שֶׁבְּכָל עֵת, עֶרֶב וָבֹקֶר וְצָהֳרָיִם. הַטּוֹב, כִּי לֹא כָלוּ רַחֲמֶיךָ, הַמְרַחֵם, כִּי לֹא תַמּוּ חֲסָדֶיךָ, כִּי מֵעוֹלָם קִוִּינוּ לָךְ.","cond":[]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת, שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה, בִּימֵי מַתִּתְיָה בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְשַׁכְּחָם תּוֹרָתָךְ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנָךְ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וּטְמֵאִים בְּיַד טְהוֹרִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, לְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמָךְ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כָּךְ בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ בְּהַלֵּל גָּמוּר וּבְהוֹדָאָה, וְעָשִׂיתָ עִמָּהֶם נִסִּים וְנִפְלָאוֹת, וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל, סֶלָה.","cond":["chanuka"]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת, שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה, בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים, בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ, וְעָשִׂיתָ עִמָּהֶם נִסִּים וְנִפְלָאוֹת, וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל, סֶלָה.","cond":["purim"]},{"kind":"text","text":"וְעַל כֻּלָּם יִתְבָּרַךְ וְיִתְרוֹמַם וְיִתְנַשֵּׂא תָמִיד, שִׁמְךָ מַלְכֵּנוּ, לְעוֹלָם וָעֶד. וְכָל הַחַיִּים יוֹדוּךָ סֶּלָה.","cond":[]},{"kind":"special","text":"וּכְתֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶךָ.","cond":["ayt"]},{"kind":"text","text":"וִיהַלְלוּ וִיבָרְכוּ אֶת שִׁמְךָ הַגָּדוֹל, בֶּאֱמֶת, לְעוֹלָם כִּי טוֹב, הָאֵל יְשׁוּעָתֵנוּ וְעֶזְרָתֵנוּ סֶלָה, הָאֵל הַטּוֹב. בָּרוּךְ אַתָּה יֻהֻוֻהֻ, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת.","cond":[]},{"kind":"text","text":"שִׂים שָׁלוֹם טוֹבָה וּבְרָכָה, חַיִּים, חֵן וָחֶסֶד, צְדָקָה וְרַחֲמִים, עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל עַמֶּךָ. וּבָרְכֵנוּ אָבִינוּ, כֻּלָּנוּ כְאֶחָד בְּאוֹר פָּנֶיךָ, כִּי בְאוֹר פָּנֶיךָ נָתַתָּ לָּנוּ יְהֹוָה אֱלֹהֵינוּ, תּוֹרָה וְחַיִּים, אַהֲבָה וָחֶסֶד, צְדָקָה וְרַחֲמִים, בְּרָכָה וְשָׁלוֹם. וְטוֹב בְּעֵינֶיךָ לְבָרְכֵנוּ וּלְבָרֵךְ אֶת כָּל עַמְּךָ יִשְׂרָאֵל בְּרֹב עֹז וְשָׁלוֹם.","cond":[]},{"kind":"special","text":"וּבְסֵפֶר חֵיִּים, בְּרָכָה וְשָׁלוֹם, וּפַרְנָסָה טוֹבָה וִישׁוּעָה וְנֶחָמָה, וּגְזֵרוֹת טוֹבוֹת, נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ, אֲנַחְנוּ וְכָל עַמְּךָ יִשְׂרָאֵל, לְחַיִּים טוֹבִים וּלְשָׁלוֹם.","cond":["ayt"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יוּהוּווּהוּ, הַמְּבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם. אָמֵן.","cond":[]},{"kind":"text","text":"יִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:\nאֱלֹהַי, נְצֹר לְשׁוֹנִי מֵרָע, וּשְׂפָתַי מִדַּבֵּר מִרְמָה, וְלִמְקַלְלַי נַפְשִׁי תִדֹּם, וְנַפְשִׁי כֶּעָפָר לַכֹּל תִּהְיֶה. פְּתַח לִבִּי בְּתוֹרָתֶךָ, וְאַחֲרֵי מִצְוׂתֶיךָ תִּרְדֹּף נַפְשִׁי. וְכָל הַקָּמִים עָלַי לְרָעָה, מְהֵרָה הָפֵר עֲצָתָם וְקַלְקֵל מַחְשְבוֹתָם. (יִהְיוּ כְּמֹץ לִפְנֵי רוּחַ, וּמַלְאַךְ יהוה דּוֹחֶה.) עֲשֵׂה לְמַעַן שְׁמָךְ, עֲשֵׂה לְמַעַן יְמִינָךְ, עֲשֵׂה לְמַעַן תּוֹרָתָךְ, עֲשֵׂה לְמַעַן קְדֻשָּׁתָךְ, לְמַעַן יֵחָלְצוּן יְדִידֶיךָ. הוֹשִׁיעָה יְמִינְךָ וַעֲנֵנִי.\nיִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:","cond":[]},{"kind":"instruction","text":"יש נוהגים לומר כאן תחנונים, ויש אומרים תפילה זו:\nיְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁלֹּא תַעֲלֶה קִנְאַת אֲחֵרִים עָלַי וְלֹא קִנְאָתִי עַל אֲחֵרִים, וְשֶׁלֹּא אֶכְעוֹס הַיּוֹם וְשֶׁלֹּא אַכְעִיסֶך, וְתַצִּילֵנִי מִיֵּצֶר הָרָע, וְתֵן בְּלִבִּי הַכְנָעָה וַעֲנָוָה וְיִרְאַת חֵטְא. מַלְכֵּנוּ וֵאלֹהֵינוּ, יַחֵד שִׁמְךָ בְּעוֹלָמָךְ וּבְנֵה בֵיתָךְ, שַׁכְלֵל הֵיכָלָךְ וְקַבֵּץ גָּלֻיּוֹתֵינוּ, פְּדֵה צֹאנָךְ וְשַמַּח עֲדָתָךְ בִּמְהֵרָה בְיָמֵינוּ וְתֵן חֶלְקֵנוּ בְּתוֹרָתָךְ. אָמֵן.","cond":[]},{"kind":"text","text":"עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּבְנֶה בֵית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵינוּ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתָךְ לַעֲשׂוֹת חֻקֵּי רְצוֹנָךְ וּלְעָבְדָךְ בְּלֵבָב שָׁלֵם.","cond":[]},{"kind":"header","text":"חזרת הש\"ץ","cond":[]},{"kind":"instruction","text":"חזרת הש\"ץ","cond":[]},{"kind":"text","text":"אֲדֹנָי, שְׂפָתַי תִּפְתָּח, וּפִי יַגִּיד תְּהִלָּתֶךָ:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יְהֹוָה, אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק וֵאלֹהֵי יַעֲקֹב, הָאֵל הַגָּדוֹל, הַגִּבּוֹר וְהַנּוֹרָא, אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, קוֹנֵה הַכֹּל וְזוֹכֵר חַסְדֵי אָבוֹת וּמֵבִיא גּוֹאֵל לִבְנֵי בְנֵיהֶם לְמַעַן שְׁמוֹ בְּאַהֲבָה.","cond":[]},{"kind":"special","text":"זָכְרֵנוּ לְחַיִּים, מֶלֶךְ חָפֵץ בַּחַיִּים, כָּתְבֵנוּ בְּסֵפֶר חַיִּים, לְמַעַנְךָ אֱלֹהִים חַיִּים.","cond":["ayt"]},{"kind":"text","text":"מֶלֶךְ עוֹזֵר וּמוֹשִׁיעַ וּמָגֵן. בָּרוּךְ אַתָּה יַהַוַהַ, מָגֵן אַבְרָהָם.","cond":[]},{"kind":"text","text":"אַתָּה גִּבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֵּה מֵתִים אַתָּה, רַב לְהוֹשִׁיעַ,","cond":[]},{"kind":"summer","text":"מוֹרִיד הַטָּל,","cond":["summerTal"]},{"kind":"winter","text":"מַשִּׁיב הָרוּחַ וּמוֹרִיד הַגֶּשֶׁם,","cond":["winterTal"]},{"kind":"text","text":"מְכַלְכֵּל חַיִּים בְּחֶסֶד, מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים, סוֹמֵךְ נוֹפְלִים וְרוֹפֵא חוֹלִים, וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמוּנָתוֹ לִישֵׁנֵי עָפָר. מי כָמוֹךָ בַּעַל גְּבוּרוֹת וּמִי דוֹמֶה לָךְ, מֶלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִיחַ יְשׁוּעָה.","cond":[]},{"kind":"special","text":"מִי כָמוֹךָ אַב הָרַחֲמָן, זוֹכֵר יְצוּרָיו בְּרַחֲמִים לְחַיִּים.","cond":["ayt"]},{"kind":"text","text":"וְנֶאֱמָן אַתָּה לְהַחֲיוֹת מֵתִים. בָּרוּךְ אַתָּה יֵהֵוֵהֵ, מְחַיֵּה הַמֵּתִים.","cond":[]},{"kind":"header","text":"קדושה","cond":[]},{"kind":"instruction","text":"קדושה בחזרת הש\"ץ","cond":[]},{"kind":"text","text":"נַקְדִּישָׁךְ וְנַעֲרִיצָךְ כְּנֹעַם שִׂיחַ סוֹד שַׂרְפֵי קֹדֶשׁ, הַמְשַׁלְּשִׁים לְךָ קְדֻשָּׁה, כַּכָּתוּב עַל יַד נְבִיאֶךָ: וְקָרָא זֶה אֶל זָה וְאָמַר: קָדוֹש, קָדוֹש, קָדוֹש, יהוה צְבָאוֹת, מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ:\nלְעֻמָּתָם מְשַׁבְּחִים וְאוֹמְרִים: בָּרוּךְ כְּבוֹד יהוה מִמְּקוֹמוֹ:\nוּבְדִבְרֵי קָדְשְׁךָ כָּתוּב לֵאמֹר: יִמְלֹךְ יהוה לְעוֹלָם, אֱלֹהַיִךְ צִיּוֹן לְדֹר וָדֹר, הַלְלוּיָהּ:","cond":[]},{"kind":"text","text":"אַתָּה קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ, וּקְדוֹשִׁים בְּכָל-יוֹם יְהַלְלוּךָ סֶּלָה.","cond":[]},{"kind":"special","text":"בָּרוּךְ אַתָּה יֹהֵוָה, הַמֶּלֶךְ הַקָּדוֹשׁ.","cond":["ayt"]},{"kind":"text","text":"בּרוּךְ אַתָּה יֹהֵוָה, הָאֵל הַקָּדוֹשׁ.","cond":["noayt"]},{"kind":"text","text":"אַתָּה חוֹנֵן לְאָדָם דַּעַת וּמְלַמֵּד לֶאֱנוֹשׁ בִּינָה. וְחָנֵּנוּ מֵאִתְּךָ חָכְמָה בִּינָה וָדָעַת. בָּרוּךְ אַתָּה יַהַוַהַ חוֹנֵן הַדָּעַת.","cond":[]},{"kind":"text","text":"הֲשִׁיבֵנוּ אָבִינוּ לְתוֹרָתֶךָ, וְקָרְבֵנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶךָ, וְהַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ. בָּרוּךְ אַתָּה יֵהֵוֵהֵ, הָרוֹצֶה בִּתְשׁוּבָה.","cond":[]},{"kind":"text","text":"סְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחֹל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ, כִּי אֵל טוֹב וְסַלָּח אָתָּה. בָּרוּךְ אַתָּה יֶהֶוֶהֶ, חַנּוּן הַמַּרְבֶּה לִסְלֹחַ.","cond":[]},{"kind":"text","text":"רְאֵה נָא בְעָנְיֵנוּ וְרִיבָה רִיבֵנוּ, וּמַהֵר לְגָאֳלֵנוּ גְאֻלָּה שְׁלֵמָה לְמַעַן שְׁמֶךָ, כִּי אֵל גּוֹאֵל חָזָק אָתָּה. בָּרוּךְ אַתָּה יְהְוְהְ, גוֹאֵל יִשְׂרָאֵל.","cond":[]},{"kind":"instruction","text":"בתענית ציבור אומר כאן השליח ציבור \"עננו\".","cond":["taanit"]},{"kind":"special","text":"עֲנֵנוּ אָבִינוּ עֲנֵנוּ בְּיוֹם צוֹם הַתַּעֲנִית הַזֶּה, כִּי בְצָרָה גְדוֹלָה אֲנָחְנוּ. אַל תֵּפֶן לְרִשְׁעֵנוּ, וְאַל תִּתְעַלַּם מַלְכֵּנוּ מִבַּקָּשָׁתֵנוּ, הֱיֵה נָא קָרוֹב לְשַׁוְעָתֵנוּ. טֶרֶם נִקְרָא אֵלֶיךָ אַתָּה תַעֲנֶה, נְדַבֵּר וְאַתָּה תִשְׁמַע, כַּדָּבָר שֶׁנֶּאֱמַר: וְהָיָה טֶרֶם יִקְרָאוּ וַאֲנִי אֶעֱנֶה, עוֹד הֵם מְדַבְּרִים וַאֲנִי אֶשְׁמָע: כִּי אַתָּה יהוה פּוֹדֶה וּמַצִּיל וְעוֹנֶה וּמְרַחֵם בְּכָל עֵת צָרָה וְצוּקָה. בָּרוּךְ אַתָּה יהוה, הָעוֹנֶה לְעַמּוֹ יִשְׂרָאֵל בְּעֵת צָרָה.","cond":["taanit"]},{"kind":"text","text":"רְפָאֵנוּ יְהֹוָה וְנֵרָפֵא, הוֹשִׁיעֵנוּ וְנִוָּשֵׁעָה כִּי תְהִלָּתֵנוּ אָתָּה, וְהַעֲלֵה אֲרוּכָה וּמַרְפֵּא לְכָל-תַּחֲלוּאֵינוּ וּלְכָל-מַכְאוֹבֵינוּ וּלְכָל-מַכּוֹתֵינוּ, כִּי אֵל רוֹפֵא רַחֲמָן וְנֶאֱמָן אָתָּה. בָּרוּךְ אַתָּה יֹהֹוׂהֹ, רוֹפֵא חוֹלֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"summer","text":"בָּרְכֵנוּ יְהֹוָה אֱלֹהֵינוּ בְּכָל מַעֲשֵׂי יָדֵינוּ, וּבָרֵךְ שְׁנָתֵנוּ בְּטַלְלֵי רָצוֹן בְּרָכָה וּנְדָבָה, וּתְהִי אַחֲרִיתָהּ חַיִּים וְשָׂבָע וְשָׁלוֹם כַּשָּׁנִים הַטּוֹבוֹת לִבְרָכָה. כִּי אֵל טוֹב וּמֵטִיב אַתָּה וּמְבָרֵךְ הַשָּׁנִים. בָּרוּךְ אַתָּה יִהִוִהִ, מְבָרֵךְ הַשָּׁנִים.","cond":["summerBracha"]},{"kind":"winter","text":"בָּרֵךְ עָלֵינוּ יְהֹוָה אֱלֹהֵינוּ אֶת הַשָּׁנָה הַזֹּאת וְאֶת כָּל מִינֵי תְּבוּאָתָהּ לְטוֹבָה, וְתֵן טַל וּמָטָר לִבְרָכָה עַל כָּל פְּנֵי הָאֲדָמָה, וְרַוֵּה פְּנֵי תֵבֵל וְשַׂבַּע אֶת הָעוֹלָם כֻּלּוֹ מִטּוּבָךְ, וּמַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ וּמֵעֹשֶׁר מַתְּנוֹת יָדֶיךָ. שָׁמְרָה וְהַצִּילָה שָׁנָה זוֹ מִכָּל דָּבָר רָע וּמִכָּל מִינֵי מַשְׁחִית וּמִכָּל מִינֵי פֻרְעָנוּת, וַעֲשֵׂה לָהּ תִּקְוָה טוֹבה וְאַחֲרִית שָׁלוֹם. חוּס וְרַחֵם עָלֶיהָ וְעַל כָּל תְּבוּאָתָהּ וּפֵירוֹתֶיהָ, וּבָרְכָהּ בְּגִשְׁמֵי רָצוֹן בְּרָכָה וּנְדָבָה, וּתְהִי אַחֲרִיתָהּ חַיִּים וְשָׂבָע וְשָׁלוֹם כַּשָּׁנִים הַטּוֹבוֹת לִבְרָכָה. כִּי אֵל טוֹב וּמֵטִיב אַתָּה וּמְבָרֵךְ הַשָּׁנִים. בָּרוּךְ אַתָּה יִהִוִהִ, מְבָרֵךְ הַשָּׁנִים.","cond":["winterBracha"]},{"kind":"text","text":"תְּקַע בְּשׁוֹפָר גָּדוֹל לְחֵרוּתֵנוּ, וְשָׂא נֵס לְקַבֵּץ גָּלֻיּוֹתֵינוּ, וְקַבְּצֵנוּ יַחַד מֵאַרְבַּע כַּנפוֹת הָאָרֶץ לְאַרְצֵנוּ. בָּרוּךְ אַתָּה יֻהֻוֻהֻ, מְקַבֵּץ נִדְחֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"הָשִׁיבָה שׁוֹפְטֵינוּ כְּבָרִאשׁוֹנָה, וְיוֹעֲצֵינוּ כְּבַתְּחִלָּה, וְהָסֵר מִמֶּנוּ יָגוֹן וַאֲנָחָה, וּמְלֹךְ עָלֵינוּ מְהֵרָה אַתָּה יְהֹוָה לְבַדְּךָ, בְּחֶסֶד וּבְרַחֲמִים, בְּצֶדֶק וּבְמִשְׁפָּט.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יוּהוּווּהוּ, מֶלֶךְ אוֹהֵב צְדָקָה וּמִשְׁפָּט.","cond":["noAyt"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יוּהוּווּהוּ, הַמֶּלֶךְ הַמִּשְׁפָּט.","cond":["ayt"]},{"kind":"text","text":"לַמִּינִים וְלַמַּלְשִׁינִים אַל תְּהִי תִקְוָה, וְכָל הַזֵּדִים כְּרֶגַע יֹאבֵדוּ, וְכָל אוֹיְבֶיךָ וְכָל שׂוֹנְאֶיךָ מְהֵרָה יִכָּרֵתוּ, וּמַלְכוּת הָרִשְׁעָה מְהֵרָה תְעַקֵּר וּתְשַׁבֵּר וּתְכַלֵּם וְתַכְנִיעֵם בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יָהָוָהָ, שׁוֹבֵר אוֹיְבִים וּמַכְנִיעַ זֵדִים.","cond":[]},{"kind":"text","text":"עַל הַצַּדִּיקִים וְעַל הַחֲסִידִים וְעַל שְׁאֵרִית עַמְּךָ בֵּית יִשְׂרָאֵל וְעַל זִקְנֵיהֶם וְעַל פְּלֵטַת בֵּית סוֹפְרֵיהֶם וְעַל גֵּרֵי הַצֶּדֶק וְעָלֵינוּ, יֶהֱמוּ נָא רַחֲמֶיךָ יְהֹוָה אֱלֹהֵינוּ, וְתֵן שָׂכָר טוֹב לְכָל הַבּוֹטְחִים בְּשִׁמְךָ בֶאֱמֶת, וְשִׂים חֶלְקֵנוּ עִמָּהֶם, וּלְעוֹלָם לֹא נֵבוֹשׁ כִּי בְךָ בָטַחְנוּ, וְעַל חַסְדְּךָ הַגָּדוֹל בֶּאֱמֶת נִשְׁעָנְנוּ. בָּרוּךְ אַתָּה יוּהוּווּהוּ, מִשְׁעָן וּמִבְטָח לַצַּדִּיקִים.","cond":[]},{"kind":"text","text":"תִּשְׁכּוֹן בְּתוֹךְ יְרוּשָׁלַיִם עִירְךָ כַּאֲשֶׁר דִּבַּרְתָּ, וְכִסֵּא דָוִד עַבְדְּךָ מְהֵרָה בְתוֹכָהּ תָּכִין, וּבְנֵה אוֹתָהּ בִּנְיַן עוֹלָם בִּמְהֵרָה בְיָמֵינוּ.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יֻהֻוֻהֻ, בּוֹנֵה יְרוּשָׁלָיִם.","cond":["noTishaaBeav"]},{"kind":"special","text":"נַחֵם יהוה אֱלֹהֵינוּ אֶת אֲבֵלֵי צִיּוֹן וְאֶת אֲבֵלֵי יְרוּשָׁלַיִם, וְאֶת הָעִיר הַחֲרֵבָה וְהַבְּזוּיָה וְהַשוֹמֵמָה, מִבְּלִי בָנֶיהָ הִיא יוֹשֶׁבֶת, וְרֹאשָׁהּ חָפוּי כְּאִשָּׁה עֲקָרָה שֶׁלֹּא יָלָדָה. וַיְבַלְּעוּהָ לִגְיוֹנִים וַיִּירָשׁוּהָ, וַיַטִּילוּ אֶת עַמְּךָ יִשְׂרָאֵל לַחֶרֶב, וַיַּהַרְגוּ בְזָדוֹן חֲסִידָי עֶלְיוֹן. עַל כֵּן צִיּוֹן בְּמֶרֶר תִּבְכֶּה וִירוּשָׁלַיִם תִּתֵּן קוֹלָהּ. לִבִּי לִבִּי עַל חַלְלֵיהֶם, מֵעַי מֵעַי עַל הֲרוּגֵיהֶם. כִּי אַתָּה יהוה בָּאֵשׁ הִצַּתָּהּ, וּבָאֵשׁ אַתָּה עָתִיד לִבְנוֹתָהּ, כַּכָּתוּב: וַאֲנִי אֶהְיֶה לָהּ נְאֻם יְהוה חוֹמַת אֵשׁ סָבִיב, וּלְכָבוֹד אֶהְיֶה בְתוֹכָהּ: בָּרוּךְ אַתָּה יהוה, מְנַחֵם צִיּוֹן בְּבִנְיַן יְרוּשָׁלַיִם.","cond":["tishaaBeav"]},{"kind":"text","text":"אֶת צֶמַח דָּוִד עַבְדְּךָ מְהֵרָה תַצְמִיחַ, וְקַרְנוֹ תָרוּם בִּישׁוּעָתֶךָ. כִּי לִישׁוּעָתְךָ קִוִּינוּ וְצִפִּינוּ כָּל הַיּוֹם. בָּרוּךְ אַתָּה יִהִוִהִ, מַצְמִיחַ קֶרֶן יְשׁוּעָה.","cond":[]},{"kind":"text","text":"שְׁמַע קוֹלֵנוּ יְהֹוָה אֱלֹהֵינוּ, אָב הָרַחֲמָן רַחֵם עָלֵינוּ, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ, כִּי אֵל שׁוֹמֵעַ תְּפִלּוֹת וְתַחֲנוּנִים אָתָּה, וּמִלְּפָנֶיךָ מַלְכֵּנוּ, רֵיקָם אַל תְּשִׁיבֵנוּ. חָנֵּנוּ וַעֲנֵנוּ וּשְׁמַע תְּפִלָּתֵנוּ. כִּי אַתָּה שׁוֹמֵעַ תְּפִלַּת כָּל פֶּה. בָּרוּךְ אַתָּה יהוה, שׁוֹמֵעַ תְּפִלָּה.","cond":[]},{"kind":"text","text":"רְצֵה יְהֹוָה אֱלֹהֵינוּ בְּעַמְּךָ יִשְׂרָאֵל, וּלִתְפִלָּתָם שְׁעֵה, וְהָשֵׁב הָעֲבוֹדָה לִדְבִיר בֵּיתֶךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם מְהֵרָה בְאַהֲבָה תְּקַבֵּל בְּרָצוֹן, וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּךָ.","cond":[]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, זִכְרוֹן יְרוּשָׁלַיִם עִירָךְ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן לְחֶסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["rh"]},{"kind":"special","text":"רֹאשׁ הַחֹדֶשׁ הַזֶּה,","cond":["rh"]},{"kind":"special","text":"לְרַחֵם בּוֹ עָלֵינוּ וּלְהוֹשִׁיעֵנוּ. זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. בִּדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וַחֲמוֹל וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["rh"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, זִכְרוֹן יְרוּשָׁלַיִם עִירָךְ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן לְחֶסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["sucot"]},{"kind":"special","text":"חַג הַסֻּכּוֹת הַזֶּה, בְּיוֹם מִקְרָא קֹדֶשׁ הַזֶּה,","cond":["sucot"]},{"kind":"special","text":"לְרַחֵם בּוֹ עָלֵינוּ וּלְהוֹשִׁיעֵנוּ. זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. בִּדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וַחֲמוֹל וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["sucot"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, זִכְרוֹן יְרוּשָׁלַיִם עִירָךְ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן לְחֶסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["pesach"]},{"kind":"special","text":"חַג הַמַּצּוֹת הַזֶּה, בְּיוֹם מִקְרָא קֹדֶשׁ הַזֶּה,","cond":["pesach"]},{"kind":"special","text":"לְרַחֵם בּוֹ עָלֵינוּ וּלְהוֹשִׁיעֵנוּ. זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. בִּדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וַחֲמוֹל וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["pesach"]},{"kind":"text","text":"וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים תַּחְפֹּץ בָּנוּ וְתִרְצֵנוּ, וְתֶחֱזֶינָה עֵינֵינוּ בְּשׁוּבְךָ לְצִיּוֹן בְּרַחֲמִים. בָּרוּךְ אַתָּה יִהִוִהִ, הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן.","cond":[]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שֶׁאַתָּה הוּא יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ לְעוֹלָם וָעֶד, צוּרֵנוּ צוּר חַיֵּינוּ וּמָגֵן יִשְׁעֵנוּ אַתָּה הוּא לְדֹר וָדֹר. נוֹדֶה לְּךָ וּנְסַפֵּר תְּהִלָּתֶךָ, עַל חַיֵּינוּ הַמְּסוּרִים בְּיָדֶךָ, וְעַל נִשְׁמוֹתֵינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּיךָ שֶׁבְּכָל יוֹם עִמָּנוּ, וְעַל נִפְלְאוֹתֶיךָ וְטוֹבוֹתֶיךָ שֶׁבְּכָל עֵת, עֶרֶב וָבֹקֶר וְצָהֳרָיִם. הַטּוֹב, כִּי לֹא כָלוּ רַחֲמֶיךָ, הַמְרַחֵם, כִּי לֹא תַמּוּ חֲסָדֶיךָ, כִּי מֵעוֹלָם קִוִּינוּ לָךְ.","cond":[]},{"kind":"header","text":"מודים דרבנן","cond":[]},{"kind":"instruction","text":"מודים דרבנן:","cond":[]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שֶׁאַתָּה הוּא יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי כָל בָּשָׁר, יוֹצְרֵנוּ יוֹצֵר בְּרֵאשִׁית. בְּרָכוֹת וְהוֹדָאוֹת לְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ, עַל שֶׁהֶחֱיִיתָנוּ וְקִיַּמְתָּנוּ. כֵּן תְּחַיֵּנוּ וּתְחָנֵּנוּ וְתֶאֱסוֹף גָּלֻיּוֹתֵינוּ לְחַצְרוֹת קָדְשֶׁךָ, לִשְׁמֹר חֻקֶּיךָ וְלַעֲשׂוֹת רְצוֹנְךָ וּלְעָבְדְךָ בְלֵבָב שָׁלֵם, עַל שֶׁאֲנַחְנוּ מוֹדִים לָךְ, בָּרוּךְ אֵל הַהוֹדָאוֹת.","cond":[]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת, שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה, בִּימֵי מַתִּתְיָה בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְשַׁכְּחָם תּוֹרָתָךְ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנָךְ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וּטְמֵאִים בְּיַד טְהוֹרִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, לְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמָךְ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כָּךְ בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ בְּהַלֵּל גָּמוּר וּבְהוֹדָאָה, וְעָשִׂיתָ עִמָּהֶם נִסִּים וְנִפְלָאוֹת, וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל, סֶלָה.","cond":["chanuka"]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת, שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה, בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים, בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ, וְעָשִׂיתָ עִמָּהֶם נִסִּים וְנִפְלָאוֹת, וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל, סֶלָה.","cond":["purim"]},{"kind":"text","text":"וְעַל כֻּלָּם יִתְבָּרַךְ וְיִתְרוֹמַם וְיִתְנַשֵּׂא תָמִיד, שִׁמְךָ מַלְכֵּנוּ, לְעוֹלָם וָעֶד. וְכָל הַחַיִּים יוֹדוּךָ סֶּלָה.","cond":[]},{"kind":"special","text":"וּכְתֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶךָ.","cond":["ayt"]},{"kind":"text","text":"וִיהַלְלוּ וִיבָרְכוּ אֶת שִׁמְךָ הַגָּדוֹל, בֶּאֱמֶת, לְעוֹלָם כִּי טוֹב, הָאֵל יְשׁוּעָתֵנוּ וְעֶזְרָתֵנוּ סֶלָה, הָאֵל הַטּוֹב. בָּרוּךְ אַתָּה יֻהֻוֻהֻ, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת.","cond":[]},{"kind":"header","text":"ברכת כהנים","cond":["noTishaaBeav"]},{"kind":"instruction","text":"ברכת כהנים לחזרת הש\"ץ:\n\nאם לא עלו כהנים לדוכן הש\"ץ אומר או\"א (נמצא בהמשך).\n\nאם עלו שני כהנים לדוכן קוראים להם - כֹּהֲנִים:\n\nהכהנים מברכים:","cond":["noTishaaBeav"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בִּקְדֻשָּׁתוֹ שֶׁל אַהֲרֹן, וְצִוָּנוּ לְבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בְּאַהֲבָה.\n\nיְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ:\nיָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ:\nיִשָּׂא יהוה פָּנָיו אֵלֶיךָ וְיָשֵׂם לְךָ שָׁלוֹם:","cond":["noTishaaBeav"]},{"kind":"instruction","text":"הקהל אומר:","cond":["noTishaaBeav"]},{"kind":"text","text":"אַדִּיר בַּמָּרוֹם שׁוֹכֵן בִּגְבוּרָה, אַתָּה שָׁלוֹם וְשִׁמְךָ שָׁלוֹם. יְהִי רָצוֹן שֶׁתָּשִׂים עָלֵינוּ וְעַל כָּל עַמְּךָ בֵּית יִשְׂרָאֵל חַיִּים וּבְרָכָה לְמִשְׁמֶרֶת שָׁלוֹם.","cond":["noTishaaBeav"]},{"kind":"instruction","text":"הכהנים אומרים","cond":["noTishaaBeav"]},{"kind":"text","text":"רִבּוֹנוֹ שֶׁל עוֹלָם, עָשִׂינוּ מַה שֶּׁגָּזַרְתָּ עָלֵינוּ, אַף אַתָּה עֲשֵׂה עִמָּנוּ כְּמוֹ שֶׁהִבְטַחְתָּנוּ: הַשְׁקִיפָה מִמְּעוֹן קָדְשְׁךָ מִן הַשָּׁמַיִם, וּבָרֵךְ אֶת עַמְּךָ אֶת יִשְׂרָאֵל, וְאֵת הָאֲדָמָה אֲשֶׁר נָתַתָּה לָנוּ, כַּאֲשֶׁר נִשְׁבַּעְתָּ לַאֲבֹתֵינוּ, אֶרֶץ זָבַת חָלָב וּדְבָשׁ:","cond":["noTishaaBeav"]},{"kind":"instruction","text":"אם לא עלו כהנים לדוכן הש\"ץ אומר:","cond":["noTishaaBeav"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, בָּרְכֵנוּ בַּבְּרָכָה הַמְשֻׁלֶּשֶׁת בַּתּוֹרָה הַכְּתוּבָה עַל יְדֵי מֹשֶׁה עַבְדֶּךָ, הָאֲמוּרָה מִפִּי אַהֲרֹן וּבָנָיו כֹּהֲנִים עַם קְדוֹשֶׁךָ, כָּאָמוּר: יְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ: יָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ: יִשָּׂא יהוה פָּנָיו אֵלֶיךָ וְיָשֵׂם לְךָ שָׁלוֹם:","cond":["noTishaaBeav"]},{"kind":"text","text":"שִׂים שָׁלוֹם טוֹבָה וּבְרָכָה, חַיִּים, חֵן וָחֶסֶד, צְדָקָה וְרַחֲמִים, עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל עַמֶּךָ. וּבָרְכֵנוּ אָבִינוּ, כֻּלָּנוּ כְאֶחָד בְּאוֹר פָּנֶיךָ, כִּי בְאוֹר פָּנֶיךָ נָתַתָּ לָּנוּ יְהֹוָה אֱלֹהֵינוּ, תּוֹרָה וְחַיִּים, אַהֲבָה וָחֶסֶד, צְדָקָה וְרַחֲמִים, בְּרָכָה וְשָׁלוֹם. וְטוֹב בְּעֵינֶיךָ לְבָרְכֵנוּ וּלְבָרֵךְ אֶת כָּל עַמְּךָ יִשְׂרָאֵל בְּרֹב עֹז וְשָׁלוֹם.","cond":[]},{"kind":"special","text":"וּבְסֵפֶר חֵיִּים, בְּרָכָה וְשָׁלוֹם, וּפַרְנָסָה טוֹבָה וִישׁוּעָה וְנֶחָמָה, וּגְזֵרוֹת טוֹבוֹת, נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ, אֲנַחְנוּ וְכָל עַמְּךָ יִשְׂרָאֵל, לְחַיִּים טוֹבִים וּלְשָׁלוֹם.","cond":["ayt"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יוּהוּווּהוּ, הַמְּבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם. אָמֵן.","cond":[]},{"kind":"text","text":"יִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:","cond":[]},{"kind":"header","text":"אבינו מלכנו","cond":["ayt"]},{"kind":"instruction","text":"אבינו מלכנו","cond":["ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חָטָאנוּ לְפָנֶיךָ רַחֵם עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, אֵין לָנוּ מֶלֶךְ אֶלָּא אָתָּה.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה עִמָּנוּ לְמַעַן שְׁמֶךָ.\nאָבִינוּ מַלְכֵּנוּ, חַדֵּשׁ עָלֵינוּ שָׁנָה טובָה וּמְבֹרֶכֶת.\nאָבִינוּ מַלְכֵּנוּ, בַּטֵּל מֵעָלֵינוּ כָּל גְּזֵרות קָשׁות וְרָעות.\nאָבִינוּ מַלְכֵּנוּ, בַּטֵּל מַחְשְׁבות שׂוֹנְאֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, הָפֵר עֲצַת אוֹיְבֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה כָּל צַר וּמַשְׂטִין מֵעָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה דֶבֶר וְחֶרֶב וְרָעָה וְרָעָב וּשְׁבִי וּבִזָּה וּמַשְׁחִית וּמַגֵּפָה וְשָׂטָן וְיֵצֶר הָרָע וָחֳלָאִים רָעִים מִבְּנֵי בְרִיתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, שְׁלַח רְפוּאָה שְׁלֵמָה לְכָל-חוֹלֵי עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, מְנַע מַגֵּפָה מִנַּחֲלָתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, זְכֹר כִּי עָפָר אֲנָחְנוּ.\nאָבִינוּ מַלְכֵּנוּ, מְחֹל וּסְלַח לְכָל עֲוׂנוֹתֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, קְרַע רוֹעַ גְּזַר-דִּינֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, מְחֹק בְּרַחֲמֶיךָ הָרַבִּים כָּל-שִׁטְרֵי חוֹבוֹתֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, מְחֵה וְהַעֲבֵר פְּשָׁעֵינוּ מִנֶּגֶד עֵינֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר חַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר צַדִּיקִים וַחֲסִידִים.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר יְשָׁרִים וּתְמִימִים.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר פַּרְנָסָה וְכַלְכָּלָה טוֹבָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר מְחִילָה וּסְלִיחָה וְכַפָּרָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר גְּאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ בְּזִכְרוֹן טוֹב מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, הַצְמַח לָנוּ יְשׁוּעָה בְּקָרוב.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן יִשְׂרָאֵל עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, וְהָרֵם קֶרֶן מְשִׁיחֶךָ.\nאָבִינוּ מַלְכֵּנוּ, חָנֵּנוּ וַעֲנֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, הַחֲזִירֵנוּ בִתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, שְׁמַע קולֵנוּ, חוּס וְרַחֵם עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעֲנָךְ, אִם לא לְמַעֲנֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, קַבֵּל בְּרַחֲמִים וּבְרָצון אֶת תְּפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, אַל תְּשִׁיבֵנוּ רֵיקָם מִלְּפָנֶיךָ.","cond":["ayt"]},{"kind":"header","text":"יהי שם","cond":["noShacharitTachanun"]},{"kind":"special","text":"יְהִי שֵׁם יהוה מְבֹרָךְ, מֵעַתָּה וְעַד עוֹלָם: מִמִּזְרַח שֶׁמֶשׁ עַד מְבוֹאו, מְהֻלָּל שֵׁם יהוה: רָם עַל כָּל גּוֹיִם יהוה, עַל הַשָּׁמַיִם כְּבוֹדוֹ: יהוה אֲדוֹנֵנוּ, מָה אַדִּיר שִׁמְךָ בְּכָל הָאָרֶץ:","cond":["noShacharitTachanun"]},{"kind":"header","text":"תחנון","cond":["shacharitTachanun"]},{"kind":"instruction","text":"יש נוהגים שלא לומר תחנון היום, ובפרט בארץ ישראל שיכולים בקלות להגיע לירושלים לשמוח עימם בשמחת פורים דמוקפין.","cond":["shacharitTachanun","purim_meshulash_tachanun_message"]},{"kind":"text","text":"אָנָּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, תָּבֹא לְפָנֶיךָ תְּפִלָּתֵנוּ, וְאַל תִּתְעַלַּם מַלְכֵּנוּ מִתְּחִנָּתֵנוּ, שֶׁאֵין אֲנַחְנוּ עַזֵּי פָנִים וּקְשֵׁי עֹרֶף לוֹמַר לְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ צַדִּיקִים אֲנַחְנוּ וְלֹא חָטָאנוּ, אֲבָל חָטָאנוּ, עָוִינוּ, פָּשַׁעְנוּ, אֲנַחְנוּ וַאֲבוֹתֵינוּ וְאַנְשֵׁי בֵיתֵנוּ:\n\nאָשַׁמְנוּ. בָּגַדְנוּ. גָּזַלְנוּ. דִּבַּרְנוּ דוֹפִי וְלָשׁון הָרָע. הֶעֱוִינוּ. וְהִרְשַׁעְנוּ. זַדְנוּ. חָמַסְנוּ. טָפַלְנוּ שֶׁקֶר וּמִרְמָה. יָעַצְנוּ עֵצוֹת רָעוֹת. כִּזַּבְנוּ. כָּעַסְנוּ. לַצְנוּ. מָרַדְנוּ. מָרִינוּ דְבָרֶיךָ. נִאַצְנוּ. נִאַפְנוּ. סָרַרְנוּ. עָוִינוּ. פָּשַׁעְנוּ. פָּגַמְנוּ. צָרַרְנוּ. צִעַרְנוּ אָב וָאֵם. קִשִּׁינוּ עֹרֶף. רָשַׁעְנוּ. שִׁחַתְנוּ. תִּעַבְנוּ. תָּעִינוּ וְתִעֲתַעְנוּ, וְסַרְנוּ מִמִּצְוׂתֶיךָ וּמִמִּשְׁפָּטֶיךָ הַטּוֹבִים וְלֹא שָׁוָה לָנוּ. וְאַתָּה צַדִּיק עַל כָּל הַבָּא עָלֵינוּ, כִּי אֱמֶת עָשִׂיתָ. ואֲנַחְנוּ הִרְשָׁעְנוּ:","cond":["shacharitTachanun"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun"]},{"kind":"text","text":"אֵל אֶרֶךְ אַפַּיִם אַתָּה וּבַעַל הָרַחֲמִים. גְּדֻלַּת רַחֲמֶיךָ וַחֲסָדֶיךָ תִּזְכּר הַיּוֹם לְזֶרַע יְדִידֶיךָ, כְּמוֹ שְהוֹדַעְתָּ לֶעָנָו מִקֶּדֶם. וְכֵן כָּתוּב בְּתוֹרָתָךְ: וַיֵּרֶד יהוה בֶּעָנָן וַיִּתְיַצֵּב עִמּו שָׁם, וַיִּקְרָא בְשֵׁם, יהוה: וְשָׁם נֶאֱמַר:\nוַיַעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, (א) אֵל (ב) רַחוּם (ג) וְחַנּוּן, (ד) אֶרֶך (ה) אַפַּיִם, (ו) וְרַב-חֶסֶד (ז) וֶאֱמֶת: (ח) נֹצֵר חֶסֶד (ט) לָאֲלָפִים, (י) נֹשֵׂא עָוׂן (יא) וָפֶשַע (יב) וְחַטָּאָה, (יג) ונקה.\n\nרַחוּם וְחַנּוּן חָטָאנוּ לְפָנֶיךָ רַחֵם עָלֵינוּ וְהושִׁיעֵנוּ.\n\nלְדָוִד, אֵלֶיךָ יהוה נַפְשִׁי אֶשָּׂא: אֱלֹהַי, בְּךָ בָטַחְתִּי אַל אֵבוֹשָׁה, אַל יַעַלְצוּ אֹיְבַי לִי: גַּם כָּל קֹוֶיךָ לֹא יֵבֹשׁוּ, יֵבֹשׁוּ הַבּוֹגְדִים רֵיקָם: דְּרָכֶיךָ יהוה הוֹדִיעֵנִי, אֹרְחוֹתֶיךָ לַמְּדֵנִי: הַדְרִיכֵנִי בַאֲמִתֶּךָ וְלַמְּדֵנִי, כִּי אַתָּה אֱלֹהֵי יִשְׁעִי, אוֹתְךָ קִוִּיתִי כָּל הַיּוֹם: זְכֹר רַחֲמֶיךָ יהוה וַחֲסָדֶיךָ, כִּי מֵעוֹלָם הֵמָּה: חַטֹּאות נְעוּרַי וּפְשָׁעַי אַל תִּזְכֹּר, כְּחַסְדְּךָ זְכָר לִי אַתָּה, לְמַעַן טוּבְךָ יהוה: טוֹב וְיָשָׁר יהוה, עַל כֵּן יוֹרֶה חַטָּאִים בַּדָּרֶךְ: יַדְרֵךְ עֲנָוִים בַּמִּשְׁפָּט, וִילַמֵּד עֲנָוִים דַּרְכּוֹ: כָּל אָרְחוֹת יהוה חֶסֶד וֶאֱמֶת לְנֹצְרֵי בְרִיתוֹ וְעֵדֹתָיו: לְמַעַן שִׁמְךָ יהוה, וְסָלַחְתָּ לַעֲוׂנִי כִּי רַב הוּא: מִי זֶה הָאִישׁ יְרֵא יהוה, יוֹרֶנּוּ בְּדֶרֶךְ יִבְחָר: נַפְשׁוֹ בְּטוֹב תָּלִין, וְזַרְעוֹ יִירַשׁ אָרֶץ: סוֹד יהוה לִירֵאָיו וּבְרִיתוֹ לְהוֹדִיעָם: עֵינַי תָּמִיד אֶל יהוה כִּי הוּא יוֹצִיא מֵרֶשֶׁת רַגְלָי: פְּנֵה אֵלַי וְחָנֵּנִי כִּי יָחִיד וְעָנִי אָנִי: צָרוֹת לְבָבִי הִרְחִיבוּ, מִמְּצוּקוֹתַי הוֹצִיאֵנִי: רְאֵה עָנְיִי וַעֲמָלִי, וְשָׂא לְכָל חַטֹּאותָי: רְאֵה אוֹיְבַי כִּי רָבּוּ וְשִׂנְאַת חָמָס שְׂנֵאוּנִי: שָׁמְרָה נַפְשִׁי וְהַצִּילֵנִי, אַל אֵבוֹשׁ כִּי חָסִיתִי בָךְ: תֹּם וָיֹשֶׁר יִצְּרוּנִי, כִּי קִוִּיתִיךָ: פְּדֵה אֱלֹהִים אֶת יִשְׂרָאֵל מִכֹּל צָרוֹתָיו: וְהוּא יִפְדֶּה אֶת יִשְׂרָאֵל, מִכָּל עֲוׂנוֹתָיו:\n\nיהוה אֱלֹהֵי יִשְׂרָאֵל, שׁוּב מֵחֲרוֹן אַפֶּךָ, וְהִנָּחֵם עַל הָרָעָה לְעַמֶּךָ.\n\nאָבִינוּ מַלְכֵּנוּ, אָבִינוּ אָתָּה. אָבִינוּ מַלְכֵּנוּ אֵין לָנוּ מֶלֶךְ אֶלָּא אָתָּה. אָבִינוּ מַלְכֵּנוּ רַחֵם עָלֵינוּ. אָבִינוּ מַלְכֵּנוּ חָנֵּנוּ וַעֲנֵנוּ כִּי אֵין בָּנוּ מַעֲשִׂים. עֲשֵׂה עִמָּנוּ חֶסֶד לְמַעַן שִׁמְךָ הַגָּדוֹל וְהושִׁיעֵנוּ. וַאֲנַחְנוּ לֹא נֵדַע מַה נַּעֲשֶׂה כִּי עָלֶיךָ עֵינֵינוּ:\n\nזְכֹר רַחֲמֶיךָ יהֹוָה וַחֲסָדֶיךָ, כִּי מֵעוֹלָם הֵמָּה: יְהִי חַסְדְּךָ יהוה עָלֵינוּ כַּאֲשֶׁר יִחַלְנוּ לָךְ: אַל תִּזְכָּר לָנוּ עֲוׂנוֹת רִאשׁוֹנִים, מַהֵר יְקַדְּמוּנוּ רַחֲמֶיךָ, כִּי דַלּוֹנוּ מְאד: עֶזְרֵנוּ בְּשֵׁם יהוה, עֹשֶׂה שָׁמַיִם וָאָרֶץ: חָנֵּנוּ יהוה חָנֵּנוּ, כִּי רַב שָׂבַעְנוּ בוּז: בְּרֹגֶז רַחֵם תִּזְכּוֹר: בְּרֹגֶז אַהֲבָה תִזְכֹּר, בְּרֹגֶז עֲקֵדָה תִזְכֹּר, בְּרֹגֶז תְּמִימוּת תִזְכֹּר. יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְּיוֹם קָרְאֵנוּ: כִּי הוּא יָדַע יִצְרֵנוּ, זָכוּר כִּי עָפָר אֲנָחְנוּ: עָזְרֵנוּ אֱלֹהֵי יִשְׁעֵנוּ עַל דְּבָר כְּבוֹד שְׁמֶךָ, וְהַצִּילֵנוּ וְכַפֵּר עַל חַטֹּאתֵינוּ לְמַעַן שְׁמֶךָ:","cond":["shacharitTachanun"]},{"kind":"header","text":"סליחות לשבעה עשר בתמוז","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"סליחות לשבעה עשר בתמוז","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"וָאָרֶץ שָׁפַל רוּמִי, יוֹם דִּמָּה רָשָׁע לְהַכְנִיעִי, מְשׂוֹשׂ לִבִּי שָׁבַת, וְהֻשְׁלַכְתִּי מִבֵּית מַרְגּוֹעִי, אָנוּ וְאָבְלוּ פְּתָחַי, יוֹם נֶאֱסַף נְדִיבִי וְשׁוּעִי, לָכֵן אֲקוֹנֵן מִיָּמִים יָמִימָה בַּחֹדֶשׁ הָרְבִיעִי.\n\nבַּחֹדֶשׁ הָרְבִיעִי אָפְפוּ עָלַי רָעוֹת וַאֲנָחוֹת, בְּשִׁבְעָה-עָשָׂר בּוֹ, בְּאַנְחָתִי יָגַעְתִּי וְלֹא מָצָאתִי מְנוּחוֹת, גָּעֹה גָעִיתִי בִּבְכִי וְעַל כָּל-רֹאשׁ קָרְחוֹת, כִּי בְיוֹם זֶה נִשְׁתַּבּרוּ הַלֻּחוֹת. הַלֻּחוֹת יְצָאוּנִי וְסָבבוּ עָלַי תְּלָאוֹת, וְגָבְרָה יַד צָרִי וְזֵרַנִי בְּכָל-פֵּאוֹת, סָב-נָא וְהָגֵן מְיַחֲלֵי קֵץ פְּלָאוֹת, כִּי שֶׁמֶשׁ וּמָגֵן יהוה צְבָאוֹת.\n\nבַּחֹדֶשׁ הָרְבִיעִי דִּמִּיתִי עֲלוֹת מִטִּיט הַיָּוֵן וְאֵין מַעֲמִיד, בְּשִׁבְעָה עָשָׂר בּוֹ הָיִיתִי לְבִזָּה לְמַאֲכָל וּלְהַשְׁמִיד, וְלֹא מָצָאתִי מָנוֹחַ וּמַכְאוֹבִי נֶגְדִּי תָמִיד, כִּי בוֹ בֻּטַּל הַתָּמִיד. הַתָּמִיד יוֹם הוּסַר גָּבְרָה יִלְלָתִי כְּיִלְלַת אֶגְלַיִם, וּמִסְפְּדִי גָדַל כְּמִסְפֵּד הֲדַדְרִמּוֹן כִּפְלַיִם, סָב-נָא וְהַחֲיֵה רְדוּמֵינוּ, אֵל שׁוֹכֵן שָׁמַיִם, יְחַיֵּינוּ מִיּוֹמָיִם.\n\nבַּחֹדֶשׁ הָרְבִיעִי זַעַם צוּר נָשָׂאתִי וַחֲמָתוֹ בִּי הִבְעִיר, בְּשִׁבְעָה עָשָׂר בּוֹ חַלְחָלָה אֲחָזַתְנִי וְסַעַר מַסְעִיר, טוֹבוֹת נָשִׁיתִי וַתִּזְנַח מִשָּׁלוֹם נַפְשִׁי בְּתִגְרַת שֵׂעִיר, כִּי בוֹ הָבְקעָה הָעִיר. הָעִיר יוֹם הָבְקְעָה בְּקוּם תֵּימָן וּמַגְדִּיאֵל, וְאָזְלַת יָדִי וְלֹא מָצְאָה לָאֵל, סָב-נָא וְהַקְדֵּשׁ פְּלֵיטַת אֲרִיאֵל, וְהִקְדִּישׁוּ אֶת-קְדוֹשׁ יַעֲקֹב וְאֶת-אֱלֹהֵי יִשְׂרָאֵל.\n\nבַּחֹדֶשׁ הָרְבִיעִי יוֹם הוֹ הוֹ יוֹם תּוֹכֵחָה וְעֶבְרָה, בְּשִׁבְעָה עָשָׂר בּוֹ כְּבוֹדִי גָלָה וְתִפְאַרְתִּי הוּסָרָה, לְשִׁבְרִי אֵין כֵּהָה וּמַכָּתִי נַחְלָה וְרוּחִי נִשְׁבָּרָה, כִּי בוֹ שָׂרַף אַפּוֹסְטמוֹס אֶת-הַתּוֹרָה. הַתּוֹרָה יוֹם נִשְׂרפָה חֻדְּשׁוּ עָלַי יגוֹנַי, וְשָׁבְתוּ מֵעִיר קֹדֶשׁ יְשִׁישַׁי וּזְקֵנַי, סָב-נָא וְחֹן בְּעֻזְּךָ עֲדַת אֱמוּנַי, רוּחַ דַּעַת וְיִרְאַת יהוה.\n\nבַּחֹדֶשׁ הָרְבִיעִי מְעֻוָּתִי מָדַד זָר בּסַאסְּאָה וּבָהּ כָּל, בְּשִׁבְעָה עָשָׂר בּוֹ נָוִי הֵשַׁם זָר וְאֶת-יַעֲקֹב אָכַל, סְפוֹת שָׁנָה בְשָׁנָה בְּיוֹם זֶה מַמְרוּר אוֹכַל, כִּי בוֹ הָעֳמָד צֶלֶם בַּהֵיכָל. יוֹם הָעֳמָד פֶּסֶל קִנְאָה וְתוֹעֵבָה, וּבוֹ חֻבְּלָה רוּחִי וְתוֹחַלְתִּי נִכְזבָה, סָב-נָא וְרַפֵּא מְשׁוּבַת עַמְּךָ וְתֹאהֲבֵם נְדָבָה, הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה.\n\nעַל יְדֵי רַחֲמֶיךָ הָרַבִּים סְלַח לָנוּ אָבִינוּ, כִּי בְרוֹב אִוַּלְתֵּנוּ שָׁגִינוּ, מְחֹל לָנוּ מַלְכֵּנוּ, כִּי רַבּוּ עֲוׂנֵינוּ, אֵל אֶרֶךְ אַפַּיִם אַתָּה, וְדֶרֶךְ תְּשׁוּבָה לָנוּ הוֹרֵיתָ, גְּדֻלַּת רַחֲמֶיךָ וַחֲסָדֶיךָ, תִּזְכֹּר הַיּוֹם לְזֶרַע יְדִידֶיךָ, תֵּפֶן אֵלֵינוּ בְּרַחֲמִים, כִּי אַתָּה הוּא בַּעַל הָרַחֲמִים. בְּתַחֲנוּן וּבִתְפִלָּה נְקַדֵּם, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָו מִקֶּדֶם, וּמֵחֲרוֹן אַפְּךָ תָּשׁוּב, כְּמוֹ בְּתוֹרָתְךָ כָּתוּב, וּבְצֵל כְּנָפֶיךָ נֶחֱסֶה וְנִתְלוֹנָן, כְּיוֹם וַיֵּרֶד יהוה בֶּעָנָן, תַּעֲבוֹר עַל פֶּשַׁע וְתִמְחֹל אָשָׁם, כְּיוֹם וַיִּתְיַצֵּב עִמּוֹ שָׁם, תַּאֲזִין שֶׁוַע וְתַּקְשִׁיב בְּרָצוֹן מַאֲמַר, כְּיוֹם וַיִּקְרָא בְשֵׁם, יהוה, וְשָׁם נֶאֱמַר:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אֲזַי בְּבָגְדִי בְאִמְרֵי דָר מְעוֹנִי, בְּהִשְׂתָּרֵג עֲוׂנִי, הִכְבִּיד עֻלִי מוֹנִי, גָּבַר עָלַי זָר בְּמַהֲלֹם לְהַלְּמֵנִי, אַפּוֹ טָרַף וַיִּשְׂטמֵנִי. דְּרָכָיו זָנַחְתִּי אֲשֶׁר לִי הוֹרָה, הֵן עַל כֵּן הֵעִיר בִּי אַף וְזַעַם וְעֶבְרָה, זַעְמוֹ בִּי הֵרִיק וְחִצָּיו בִּי יָרָה, וַיְקִימֵנִי לוֹ לְמַטָּרָה. חָלפוּ עָלַי בְּיוֹם זֶה חָמֵשׁ תְּלָאוֹת, טָרפוּ חַיָּתִי וַיְשִׂימוּנִי לְמַשּׁוּאוֹת, יָגְעָה נַפְשִׁי יָגוֹעַ וְהַלְאוֹת, נַעֲוֵיתִי מִשְּׁמֹעַ, נִבְהַלְתִּי מֵרְאוֹת. כָּל-אֵלֶּה בְּזָכְרִי יְעוֹרְרוּנִי אֲנָחוֹת, לֶהָבָה הֱשִׂיקַתְנִי מְלַהֶטֶת כֶּסֶל וְטוּחוֹת, מִסְפֵּד מַר אַגְדִּיל וְאַרְחִיק שְׂמָחוֹת, כִּי בְיוֹם זֶה נִשְׁתַּבּרוּ הַלּוּחוֹת. נוֹעַד עָלַי זָר וַהֲמוֹנָיו הִצְמִיד, סַבּוּנִי כַמַּיִם וְטָבַעְתִּי וְאֵין מַעֲמִיד, עַל כֵּן אֲיֵלִיל בְּמוֹ פִי, וְנֶהִי אַתְמִיד, כִּי ביוֹם זֶה בֻּטַּל הַתָּמִיד. פּוֹשְׁחַי הָמוּ כַּהֲמוֹת זֶרֶם מִיכַל, צָמְתוּ בַבּוֹר חַיַּי וַיִּתְּנוּנִי לְמַאֲכָל, קָרָא עָלַי מוֹעֵד וַהֲמוֹנַי שָׁכֹל שִׁכַּל, כִּי בּיוֹם זֶה הָעֳמָד צֶלֶם בָּהֵיכָל. רַבָּתִי עָם, זָר הֵצַר וּפְתָחֶיהָ פֶּתַח הֶעֱרָה, שָׁת גַּפְנִי לְשַׁמָּה בְּיוֹם זָעַם וְעֶבְרָה, תַּאֲוָתוֹ רָאָה זָר וְיָדוֹ בְּעֹז גָּבְרָה, כִּי בְיוֹם זֶה שָׂרַף אַפּוֹסְטמוֹס אֶת-הַתּוֹרָה. חָרקוּ שֵׁן רְשָׁעִים בְּיוֹם אַף יהוה בִּי הֵעִיר, לֹא חָמַל זָר וְעִקֵּשׁ עַל יָשִׁישׁ וְצָעִיר, אַפּוֹ בִּי חָרָה וּרְשָׁפָּיו בִּי הִבְעִיר, כִּי בְיוֹם זֶה הָבְקְעָה הָעִיר. רַחֵם יהוה וְדַבֵּר עַל לֵב עֲגוּמִים, בְּשִׁבְעָה עָשָׂר לַחֹדֶשׁ יוֹשְׁבִים מִשְׁתּוֹמְמִים, יָהּ, גַּלְגֵּל עֲלֵיהֶם הֲמוֹן רַחֲמֶיךָ מִמְּרוֹמִים, אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים.\n\nשׁעֵה לְנֶאְסָר, אֲשֶׁר נִמְסַר, בְּיַד בָּבֶל וְשַׂר הָעִיר. לְךָ יֶהֱמֶה, זֶה כַמֶּה, וְיִתְחַנֵּן כְּבֶן צָעִיר. מוּלְךָ צוּר, בְּלֵב עָצוּר, הֶמְיַת מֵעָיו יַסְעִיר. יוֹם גָּבַר הָאוֹיֵב וַתִּבָּקַע הָעִיר. לְזֹאת אִכַּף, וְאֶסְפֹּק כַּף, בְּיוֹם חָמֵשׁ קְרָאוּנִי. וְעַל רֶגֶל, הָעֵגֶל, הַלּוּחוֹת יְצָאוּנִי. וְלָכַד זָר, הַמִּבְצָר, וּבְמַסְגֵּר הֱבִיאָנִי. וְגַם הִשְׁמִיד, הַתָּמִיד, וּמֵעֲשׂוֹתוֹ כְּלָאָנִי. וְהוּשָׂם אֱלִיל, בְּהֵיכָל כָּלִיל, וְדָתךָ זָר בָּאֵשׁ הִבְעִיר. מְאֹד אֶתְחַל, וָאֶתְחַלְחַל, בְּיוֹם שַׁדַּי חֲשָׂפַנִי. וְהַשְּׁפִיפוֹן, מִצָּפוֹן, כְּשִׁבּוֹלֶת שְׁטָפַנִי. וְנָהַג שְׁבִי, אֶרֶץ צְבִי, וְגַם כַּדּוּר צְנָפַנִי. יוֹם חָשַׁךְ, מְאוֹר שֵׁשַׁךְ, לְיַד פָּרַס דְּחָפַנִי. אֲכָלַנִי, הֲמָמַנִי, וְקִינָה עֲלֵי זֹאת אָעִיר. הֲלָעַד בִּי, מִשְׂגַּבִּי, הֲלָעַד אַפְּךָ יֶעְשַׁן. גְּדוֹר פִּרְצִי, בְּבֶן פַּרְצִי, וּמֵחֶדֶק לְקֹט שׁוֹשָׁן. עַיִן פְּקַח, תְּפִלָּתִי קַח, כְּמוֹ חֵלֶב הַמְּדֻשָׁן. בְּנֵה בֵית זְבוּל, וְהָשֵׁב גְּבוּל, הַכַּרְמֶל וְהַבָּשָׁן. שְׁפֹט אִלֵּם, וְאָז יְשַׁלֵּם, הַמַּבְעֶה וְהַמַּבְעִיר.\n\nאֱלֹהֵי יְשׁוּעָתֵנוּ, שְׁעֵה שַׁוְעָתֵנוּ, וּרְאֵה שׁוֹממוֹתֵינוּ, וְאֹרֶךְ גָּלוּתֵנוּ, מִדֵּי שָׁנָה בְשָׁנָה, בְּזָכְרֵנוּ עֱנוּתֵנוּ, בְּיוֹם חֲמִשָּׁה דְבָרִים, אֵרעוּ אֶת-אֲבוֹתֵינוּ. נָא אֱלֹהֵי הָרוּחוֹת, וּבוֹחֵן סִתְרֵי טוּחוֹת, שְׁעֵה שֵׂיוֹת נִדָּחוֹת, נְפוּצוֹת בְּאַרְבַּע רוּחוֹת, מִדֵּי שָׁנָה בְשָׁנָה בִּזְמַן זֶה נֶאֱנָחוֹת, בְּיוֹם עֵקֶב מַדּוּחוֹת, נִשְׁתַּבְּרוּ הַלּוּחוֹת, וּבוֹ כָּל-ימֵי שְׁנוֹתֵינוּ, נְמָרֵר עַל יְגוֹנֵנוּ. דְּלֵה מִטִּיט הַיָּוֵן, טְבוּעִים בּוֹ וְאֵין מַעֲמִיד, עֵדֶר תַּתָּה לְמַאֲכָל, לְבִזָּה וּלְהַשְׁמִיד, מִדֵּי שָׁנָה בְשָׁנָה, בְּיוֹם זֶה עֶצֶב מַצְמִיד, יוֹם בּוֹ יַד זָר הֶאֱמִיר, וּבוֹ בֻּטַּל הַתָּמִיד, עַל רֹב עֲוׂנוֹתֵינוּ, וְעֹצֶם חַטֹּאתֵינוּ. יָהּ אֲשֶׁר הַכֹּל יוּכַל, פְּדֵה מִשּׁכוֹל שָׁכַל, מִיַּד עִקֵּשׁ וְסָכָל, וּשְׁאַר יַעֲקֹב אָכַל, מִדֵּי שָׁנָה בְּשָׁנָה, בְּיוֹם זֶה מַמְרֹר אוֹכַל, בְּהַעֲמִיד זָר לְמוּלִי, בּוֹ צֶלֶם בַּהֵיכָל, עַל כָּל-קוֹרוֹתֵינוּ יִזְּלוּ דִמְעוֹתֵינוּ. שִׁבְרֵנוּ מַה-נּוֹרָא, כִּי סַרְנוּ מִמּוֹרָא, נָאוֹר עֹטֶה אוֹרָה, גְּמוּלִי לַכֹּל הוֹרָה, מִדֵּי שָׁנָה בְשָׁנָה, נֶהִי בְּיוֹם זֶה אֶחְקוֹרָה, יַעַן כִּי בוֹ שָׂרַף אַפּוֹסְטמוֹס אֶת-הַתּוֹרָה, לְזֹאת נִשְׁכְּבָה בּבָשְׁתֵּנוּ, לְשׁוֹד בֵּית תִּפְאַרְתֵּנוּ. רַחוּם יְכַפֵּר עָוׂן, וְכָל-חֲמָתוֹ לֹא יָעִיר, פְּדֵה חִישׁ מִידֵי שָׂעִיר, פְּזוּרֵי הַצֹּאן וְצָעִיר, מִדֵּי שָׁנָה בְשָׁנָה, בְּיוֹם זֶה הֶמְיַת מֵעָיו יַסְעִיר, יוֹם גָּברוּ הַזָּרִים וַתִּבָּקַע הָעִיר, כִּי הָיִינוּ לְלַעַג וָקֶלֶס לִסְבִיבוֹתֵינוּ. רַחֲמָן בְּרַחֲמִים שׁוּבָה, אֶל צִיּוֹן הָעֲלוּבָה, וְחִישׁ נָא לְאִשָּׁה עֲצוּבָה, נֶחָמָה הַכְּתוּבָה, וְאָז שִׁירָה נָנוּבָה, בִּבְנוֹתְךָ הַחֲרֵבָה, בְּקִבּוּץ נְפוּצוֹתֵינוּ, וּבְשׁוּבְךָ אֶת שְׁבוּתֵנוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, וּמִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לַחַטָּאִים, וּסְלִיחָה לַפּוֹשְׁעִים. עוֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וְרוּחַ, לֹא כְרָעָתָם לָהֶם גּוֹמֵל. אֵל, הוֹרֵתָנוּ לוֹמַר מִדּוֹת שְׁלֹשׁ עֶשְׂרֵה, זְכֹר לָנוּ הַיּוֹם בְּרִית שְׁלֹשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָו מִקֶּדֶם, וְכֵן כָּתוּב בְּתוֹרָתָךְ: וַיֵּרֶד יהוה בֶּעָנָן וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם יהוה: וְשָׁם נֶאֱמַר:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אַנְשֵׁי אֱמוּנָה אָבָדוּ, בָּאִים בְּכֹחַ מַעֲשֵׂיהֶם. גִּבּוֹרִים לַעֲמֹד בַּפֶּרֶץ, דּוֹחִים אֶת-הַגְּזֵרוֹת. הָיוּ לָנוּ לְחוֹמָה, וּלְמַחְסֶה בְּיוֹם זָעַם. זוֹעֲכִים אַף בְּלַחֲשָׁם, חֵמָה עָצרוּ בְּשַׁוְּעָם. טֶרֶם קְרָאוּךָ עֲנִיתָם, יוֹדְעִים לַעֲתֹר וּלְרַצּוֹת. כְּאָב רִחַמְתָּ לְמַעֲנָם, לֹא הֱשִׁיבוֹתָ פְנֵיהֶם רֵיקָם. מֵרֹב עֲוׂנֵינוּ אֲבַדְנוּם, נֶאֶסְפוּ מֶנּוּ בַּחֲטָאֵינוּ. סָעוּ הֵמָּה לִמְנוּחוֹת, עָזבוּ אוֹתָנוּ לַאֲנָחוֹת. פַּסּוּ גוֹדְרֵי גָדֵר, צֻמְּתוּ מְשִׁיבֵי חֵמָה. קָמִים בַּפֶּרֶץ אַיִן, רְאוּיִים לְרַצּוֹתְךָ אָפֵסוּ. שׁוֹטַטְנוּ בְּאַרְבַּע פִּנּוֹת, תְּרוּפָה לֹא מָצָאנוּ. שַׁבְנוּ אֵלֶיךָ בּבֹשֶׁת פָּנֵינוּ, לשַׁחֲרָךְ אֵל בְּעֵת צָרוֹתֵינוּ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, וּמִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לַחַטָּאִים, וּסְלִיחָה לַפּוֹשְׁעִים. עוֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וְרוּחַ, לֹא כְרָעָתָם לָהֶם גּוֹמֵל. אֵל, הוֹרֵתָנוּ לוֹמַר מִדּוֹת שְׁלֹשׁ עֶשְׂרֵה, זְכֹר לָנוּ הַיּוֹם בְּרִית שְׁלֹשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָו מִקֶּדֶם, וְכֵן כָּתוּב בְּתוֹרָתָךְ: וַיֵּרֶד יהוה בֶּעָנָן וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם יהוה: וְשָׁם נֶאֱמַר:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"תָּמַהְנוּ מֵרָעוֹת, תָּשַׁשׁ כֹּחֵנוּ מִצָּרוֹת. שַׁחְנוּ עַד לִמְאֹד, שָׁפַלְנוּ עַד עָפָר. רַחוּם כָּךְ הִיא מִדָּתֵנוּ, קְשֵׁי עֹרֶף וּמַמְרִים אֲנַחְנוּ. צָעַקְנוּ בְּפִינוּ חָטָאנוּ, פְּתַלְתּוֹל וְעִקֵּשׁ לִבֵּנוּ. עֶלְיוֹן, רַחֲמֶיךָ מֵעוֹלָם, סְלִיחָה עִמְּךָ הִיא. נִחָם עַל הָרָעָה, מַטֵּה כְלַפֵּי חֶסֶד. לֹא תִתְעַלַּם בְּעִתּוֹת כָּאֵל, כִּי בְצָרָה גְדוֹלָה אֲנָחְנוּ. יִוָּדַע לְעֵינֵי הַכֹּל, טוּבְךָ וְחַסְדְּךָ עִמָּנוּ. חֲתֹם פִּי-שָׂטָן, וְאַל יַשְׂטִין עָלֵינוּ, זְעֹם בּוֹ ויִדֹּם. וְיַעֲמֹד מֵלִיץ טוֹב לְצַדְּקֵנוּ, הוּא יַגִּיד יָשְׁרֵנוּ. דְּרָכֶיךָ רַחוּם וְחַנּוּן גִּלִּיתָ לְנֶאֱמַן בָּיִת. בְּבַקְשׁוֹ אָז מִלּפָנֶיךָ, אֱמוּנָתךָ הוֹדַעְתָּ לּוֹ.","cond":["shacharitTachanun","17tammuz"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, וּמִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לַחַטָּאִים, וּסְלִיחָה לַפּוֹשְׁעִים. עוֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וְרוּחַ, לֹא כְרָעָתָם לָהֶם גּוֹמֵל. אֵל, הוֹרֵתָנוּ לוֹמַר מִדּוֹת שְׁלֹשׁ עֶשְׂרֵה, זְכֹר לָנוּ הַיּוֹם בְּרִית שְׁלֹשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָו מִקֶּדֶם, וְכֵן כָּתוּב בְּתוֹרָתָךְ: וַיֵּרֶד יהוה בֶּעָנָן וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם יהוה: וְשָׁם נֶאֱמַר:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"וּכְשֶׁחָטאוּ יִשְׂרָאֵל בַּמִּדְבָּר, עָמַד מֹשֶׁה בִּתְפִלָּה לְפָנֶיךָ, וּבִקֵּשׁ רַחֲמִים עַל עַמְּךָ יִשְׂרָאֵל וְכָךְ אָמַר בִּתְפִלָּתוֹ: סְלַח-נָא לַעֲוׂן הָעָם הַזֶּה כְּגֹדֶל חַסְדֶּךָ, וְכַאֲשֶׁר נָשָׂאתָה לָעָם הַזֶּה מִמִּצְרַיִם וְעַד-הֵנָּה: אַף אַתָּה הֱשִׁיבוֹתָ לוֹ כְּדַרְכֵי טוּבְךָ בִּשַּׂרְתּוֹ וַחֲנַנְתּוֹ וְאָמַרְתָּ לוֹ: סָלַחְתִּי כִּדְבָרֶךָ:\n\nדָּנִיֵּאל אִישׁ חֲמוּדוֹת אָמַר לְפָנֶיךָ: הַטֵּה אֱלֹהַי אָזְנְךָ וּשֲׁמָע, פְּקַח עֵינֶיךָ וּרְאֵה שֹׁמְמֹתֵינוּ וְהָעִיר אֲשֶׁר-נִקְרָא שִׁמְךָ עָלֶיהָ, כִּי לֹא עַל-צִדְקֹתֵינוּ אֲנַחְנוּ מַפִּילִים תַּחֲנוּנֵינוּ לְפָנֶיךָ, כִּי עַל-רַחֲמֶיךָ הָרַבִּים: אֲדֹנָי שְׁמָעָה, אֲדֹנָי סְלָחָה, אֲדֹנָי הַקְשִׁיבָה וַעֲשֵׂה אַל-תְּאַחַר, לְמַעֲנְךָ אֱלֹהַי כִּי-שִׁמְךָ נִקְרָא עַל-עִירְךָ וְעַל עַמֶּךָ: וְלִירוּשָׁלַיִם עִירָךְ אָמַרְתָּ לָהּ: הִנְנִי נִשְׁפָּט אוֹתָךְ עַל-אָמְרֵךְ לֹא חָטָאתִי: אֲנַחְנוּ בּוֹשְׁנוּ בְּמַעֲשֵׂינוּ וְנִכְלַמְנוּ בַּעֲוׂנוֹתֵינוּ, אֵין לָנוּ פֶּה לְהָשִׁיב וְלֹא מֵצַח לְהָרִים רֹאשׁ.\n\nאֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אַל תַּעַשׂ עִמָּנוּ כָּלָה, תֹּאחֵז יָדְךָ בַּמִּשְׁפָּט. בְּבֹא תוֹכֵחָה נֶגְדֶּךָ, שְׁמֵנוּ מִסִּפְרְךָ אַל תֶּמַח. גִּשְׁתְּךָ לַחֲקֹר מוּסָר, רַחֲמֶיךָ יְקַדְּמוּ רָגְזֶךָ. דַּלּוּת מַעֲשִׂים בְּשׁוּרֶךָ, קָרֵב צֶדֶק מֵאֵלֶיךָ. הוֹרֵנוּ, בְּזַעֲקֵנוּ לָךְ, צַו יְשׁוּעָתֵנוּ בְּמַפְגִּיעַ. וְתָשִׁיב שְׁבוּת אָהֳלֵי תָם, פְּתָחָיו רְאֵה כִּי שָׁמֵמוּ. זְכֹר נָאַמְתָּ, עֵדוּת לֹא תִשָּׁכַח מִפִּי זַרְעוֹ. חוֹתַם תְּעוּדָה תַּתִּיר, סוֹדְךָ שִׂים בְּלִמּוּדֶיךָ. טַבּוּר אַגַּן הַסַּהַר, נָא אַל יֶחְסַר הַמָּזֶג. יָהּ, דַּע אֶת-יִשְׂרָאֵל אֲשֶׁר יְדָעוּךָ, מַגֵּר אֶת-הַגּוֹיִם אֲשֶׁר לֹא יְדָעוּךָ. כִּי תָשִׁיב לְבִצָּרוֹן, לְכוּדִים אֲסִירֵי הַתִּקְוָה.\n\nאָשַׁמְנוּ מִכָּל-עָם, בֹּשְׁנוּ מִכָּל-גּוֹי. גָּלָה מִמֶּנּוּ מָשׂוֹשׂ, דָּוֶה לִבֵּנוּ בַּחֲטָאֵינוּ. הָחְבַּל אֶוְיֵינוּ, וְנִפְרָע פְּאֵרֵנוּ. זְבוּל מִקְדָּשֵׁנוּ, חָרֵב בַּעֲוֹנֵינוּ. טִירָתֵנוּ הָיְתָה לְשַׁמָּה, יְפִי אַדְמָתֵנוּ לְזָרִים, כֹּחֵנוּ לְנָכְרִים. לְעֵינֵינוּ עָשְׁקוּ עֲמָלֵנוּ, מְמֻשָּׁךְ וּמוֹרָט מִמֶּנּוּ. נָתְנוּ עֻלָּם עָלֵינוּ, סָבַלְנוּ עַל שִׁכְמֵנוּ. עֲבָדִים מָשְׁלוּ בָנוּ, פּוֹרֵק אֵין מִיָּדָם. צָרוֹת רַבּוֹת סְבָבוּנוּ, קְרָאנוּךָ יהוה אֱלֹהֵינוּ. רָחַקְתָּ מִמֶּנּוּ בַּעֲוׂנֵינוּ, שַׁבְנוּ מֵאַחֲרֶיךָ, תָּעִינוּ כַּצֹּאן וְאָבָדְנוּ. וַעֲדַיִן לֹא שַׁבְנוּ מִתְּעִיָּתֵנוּ, וְהֵיאַךְ נָעִיז פָּנֵינוּ, וְנַקְשֶׁה עָרְפֵּנוּ, לוֹמַר לְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ צַדִּיקִים אֲנַחְנוּ וְלֹא-חָטָאנוּ.\n\nעֶזְרָא הַסּוֹפֵר אָמַר לְפָנֶיךָ: אֱלֹהַי, בֹּשְׁתִּי וְנִכְלַמְתִּי לְהָרִים אֱלֹהַי פָּנַי אֵלֶיךָ, כִּי עֲוׂנֹתֵינוּ רָבוּ לְמַעְלָה רֹאשׁ, וְאַשְׁמָתֵנוּ גָדְלָה עַד לַשָּׁמָיִם: וְאַתָּה אֱלוֹהַּ סְלִיחוֹת, חַנּוּן ורַחוּם, אֶרֶךְ-אַפַּיִם וְרַב-חֶסֶד, וְלֹא עֲזַבְתָּם. אַל תַּעַזְבֵנוּ אָבִינוּ, אַל תִּטְּשֵׁנוּ מַלְכֵּנוּ, וְאַל תִּשְׁכָּחֵנוּ יוֹצְרֵנוּ, וְאַל תַּעַשׂ עִמָּנוּ כָלָה בְּגָלוּתֵנוּ, וְקַיֵּם לָנוּ יהוה אֱלֹהֵינוּ אֶת-הַדָּבָר שֶׁהִבְטַחְתָּנוּ, עַל יְדֵי יִרְמְיָה חוֹזָךְ, כָּאָמוּר: בַּיָּמִים הָהֵם וּבָעֵת הַהִיא, נְאֻם-יהוה, יבֻקַּשׁ אֶת-עֲוׂן יִשְׂרָאֵל וְאֵינֶנּוּ, וְאֶת-חַטֹּאת יְהוּדָה וְלֹא תִמָּצֶאנָה, כִּי אֶסְלַח לַאֲשֶׁר אַשְׁאִיר: וְאַל יעַכֵּב לפָנֶיךָ כָּל-חֵטְא וְעוׂן אֶת תְּפִלָּתֵנוּ, וּמְחוֹל וּסְלַח לְכָל-עֲוׂנוֹתֵינוּ, כִּי אֵל טוֹב וסַלָּח אָתָּה.\n\nמַה-נֹּאמַר לְפָנֶיךָ יוֹשֵׁב מָרוֹם, וּמַה נְּסַפֵּר לְפָנֶיךָ שׁוֹכֵן שְׁחָקִים, הֲלֹא הַנִּסְתָּרוֹת והַנִּגְלוֹת אַתָּה יוֹדֵעַ, אַתָּה יוֹדֵעַ רָזֵי עוֹלָם, וְתַעֲלוּמוֹת סִתְרֵי כָל-חָי, אַתָּה חוֹפֵשׂ כָּל-חַדְרֵי בָטֶן, רֹאֶה כלָיוֹת וָלֵב. אֵין דָּבָר נֶעְלָם מִמָּךְ, וְאֵין נִסְתָּר מִנֶּגֶד עֵינֶיךָ.\n\nיְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּמְחֹל לָנוּ אֶת-כָּל-חַטֹּאתֵינוּ, וּתְכַפֵּר לָנוּ אֶת-כָּל-עֲוׂנוֹתֵינוּ, וְתִמְחֹל וְתִסְלַח לכָל-פְּשָׁעֵינוּ, וְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ: סְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחֹל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי, טוֹב וְסַלָּח, וְרַב-חֶסֶד לְכָל-קֹרְאֶיךָ: לְמַעַן-שִׁמְךָ יהוה, וְסָלַחְתָּ לַעֲוׂנִי כִּי רַב-הוּא: לְמַעַן-שִׁמְךָ יהוה תְּחַיֵּנִי, בְּצִדְקָתְךָ תוֹצִיא מִצָּרָה נַפְשִׁי: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב-לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה: יהוה צְבָאוֹת, אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם-קָרְאֵנוּ: הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם:","cond":["shacharitTachanun","17tammuz"]},{"kind":"text","text":"וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית, וְהִרְבָּה לְהָשִׁיב אַפּוֹ וְלֹא יָעִיר כָּל חֲמָתוֹ: אַתָּה יהוה, לֹא תִכְלָא רַחֲמֶיךָ מִמֶּנִּי, חַסְדְּךָ וַאֲמִתְּךָ תָּמִיד יִצְּרוּנִי: הוֹשִׁיעֵנוּ יהוה אֱלֹהֵינוּ וְקַבְּצֵנוּ מִן הַגּוֹיִם, לְהֹדוֹת לְשֵׁם קָדְשֶׁךָ, לְהִשְׁתַּבֵּחַ בִּתְהִלָּתֶךָ: אִם עֲוׂנוֹת תִּשְמָר יָהּ, אֲדֹנָי, מִי יַעֲמֹד: כִּי עִמְּךָ הַסְּלִיחָה, לְמַעַן תִּוָּרֵא: לֹא כַחֲטָאֵינוּ עָשָׂה לָנוּ, וְלֹא כַעֲוׂנֹתֵינוּ גָמַל עָלֵינוּ. אִם עֲוׂנֵינוּ עָנוּ בָנוּ, יהוה, עֲשֵׂה לְמַעַן שְׁמֶךָ. זְכֹר רַחֲמֶיךָ יהוה וַחֲסָדֶיךָ, כִּי מֵעוֹלָם הֵמָּה: יַעַנְךָ יהוה בְּיוֹם צָרָה, יְשַׂגֶּבְךָ שֵׁם אֱלֹהֵי יַעֲקֹב: יהוה הושִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ: אָבִינוּ מַלְכֵּנוּ, חָנֵּנוּ וַעֲנֵנוּ, כִּי אֵין בָּנוּ מַעֲשִׂים. עֲשֵׂה עִמָּנוּ צְדָקָה כְּרֹב רַחֲמֶיךָ, וְהוֹשִׁיעֵנוּ לְמַעַן שְׁמֶךָ.\n\nוְעַתָּה אֲדֹנָי אֱלֹהֵינוּ אֲשֶׁר הוֹצֵאתָ אֶת עַמְּךָ מֵאֶרֶץ מִצְרַיִם בְּיָד חֲזָקָה, וַתַּעַשׂ לְךָ שֵׁם כַּיּוֹם הַזֶּה, חָטָאנוּ רָשָׁעְנוּ: אֲדֹנָי, כְּכָל צִדְקֹתֶךָ יָשָׁב נָא אַפְּךָ וַחֲמָתְךָ מֵעִירְךָ יְרוּשָׁלַיִם הַר קָדְשֶׁךָ, כִּי בַחֲטָאֵינוּ וּבַעֲוׂנוֹת אֲבֹתֵינוּ, יְרוּשָׁלִַם וְעַמְּךָ לְחֶרְפָּה לְכָל סְבִיבֹתֵינוּ: וְעַתָּה שְׁמַע אֱלֹהֵינוּ אֶל תְּפִלַּת עַבְדְּךָ וְאֶל תַּחֲנוּנָיו, וְהָאֵר פָּנֶיךָ עַל מִקְדָּשְׁךָ הַשָּׁמֵם, לְמַעַן אֲדֹנָי: הַטֵּה אֱלֹהַי אָזְנְךָ וּשְׁמָע, פְּקַח עֵינֶיךָ וּרְאֵה שֹׁמְמֹתֵינוּ וְהָעִיר אֲשֶׁר נִקְרָא שִׁמְךָ עָלֶיהָ, כִּי לֹא עַל צִדְקֹתֵינוּ אֲנַחְנוּ מַפִּילִים תַּחֲנוּנֵינוּ לְפָנֶיךָ, כִּי עַל רַחֲמֶיךָ הָרַבִּים: אֲדֹנָי שְׁמָעָה, אֲדֹנָי סְלָחָה, אֲדֹנָי הַקֲשִׁיבָה וַעֲשֵׂה אַל תְּאַחַר, לְמַעֲנְךָ אֱלֹהַי, כִּי שִׁמְךָ נִקְרָא עַל עִירְךָ וְעַל עַמֶּךָ:\n\nאָבִינוּ אָב הָרַחֲמָן, הַרְאֵנוּ אוֹת לְטוֹבָה וְקַבֵּץ נְפוּצוֹתֵינוּ מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ. יַכִּירוּ וְיֵדְעוּ כָּל הַגּוֹיִם, כִּי אַתָּה יהוה אָבִינוּ אָתָּה, אֲנַחְנוּ הַחֹמֶר וְאַתָּה יֹצְרֵנוּ וּמַעֲשֵׂה יָדְךָ כֻּלָּנוּ: אָבִינוּ מַלְכֵּנוּ, צוּרֵנוּ מַלְכֵּנוּ וְגוֹאֲלֵנוּ, חוּסָה יהוה עַל עַמֶּךָ וְאַל תִּתֵּן נַחֲלָתְךָ לְחֶרְפָּה לִמְשָׁל בָּם גּוֹיִם, לָמָּה יֹאמְרוּ בָעַמִּים אַיֵּה אֱלֹהֵיהֶם: יָדַעְנוּ יהוה כִּי חָטָאנוּ וְאֵין מִי יַעֲמֹד בַּעֲדֵנוּ, אֶלָּא שִׁמְךָ הַגָּדוֹל יַעֲמָד לָנוּ בְּעֵת צָרָה. וּכְרַחֵם אָב עַל בָּנִים רַחֵם עָלֵינוּ. חֲמֹל עַל עַמָּךְ וְרַחֵם עַל נַחֲלָתָךְ, חוּסָה נָּא כְּרֹב רַחֲמֶיךָ, חָנֵנוּ מַלְכֵּנוּ וַעֲנֵנוּ. לְךָ יהוה הַצְּדָקָה, עֹשֵׂה נִפְלָאוֹת בְּכָל עֵת וָעֵת. הַבֵּט נָא וְהוֹשִׁיעָה נָּא צֹאן מַרְעִיתֶךָ. אַל יִמְשָׁל בָּנוּ קֶצֶף, כִּי לְךָ יהוה הַיְשׁוּעָה, בְּךָ תוֹחַלְתֵּנוּ. אֱלוֹהַּ סְלִיחוֹת, אָנָּא סְלַח נָא. כִּי אֵל טוֹב וְסַלָּח אָתָּה. אָנָּא מֶלֶךְ רַחוּם וְחַנּוּן, זְכֹר וְהַבֵּט לִבְרִית בֵּין הַבְּתָרִים, וְתֵרָאֶה לְפָנֶיךָ עֲקֵדַת יָחִיד. וּלְמַעַן יִשרָאֵל אָבִינוּ, אַל תַּעַזְבִנוּ אָבִינוּ וְאַל תִּטְּשֵנוּ מַלְכֵּנוּ, וְאַל תִּשְׁכָּחֵנוּ יוֹצְרֵנוּ, וְאַל תַּעַשׂ עִמָּנוּ כָלָה בְּגָלוּתֵנוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.\n\nאֵין כָּמוֹך חַנּוּן וְרַחוּם, אֱלֹהֵינוּ, אֵין כָּמוֹךָ אֵל אֶרֶך אַפַּיִם וְרַב חֶסֶד וֶאֱמֶת. הוֹשִׁיעֵנוּ וְרַחֲמֵנוּ, מֵרַעַשׁ וּמֵרֹגֶז הַצִּילֵנוּ. זְכֹר לַעֲבָדֶיך לְאַבְרָהָם לְיִצְחָק וּלְיַעֲקֹב, אַל תֵּפֶן אֶל קְשִׁי הָעָם הַזֶּה וְאֶל רִשְׁעוֹ וְאֶל חַטָּאתוֹ: שׁוּב מֵחָרוֹן אַפֶּךָ, וְהִנָּחֵם עַל הָרָעָה לְעַמֶּךָ: וְהָסֵר מִמֶּנּוּ מַכַּת הַמָּוֶת כִּי רַחוּם אָתָּה, כִּי כֵן דַּרְכְּךָ לַעֲשׂוֹת חֶסֶד חִנָּם בְּכָל דוֹר וָדוֹר. אָנָּא יהוה הוֹשִׁיעָה נָּא, אָנָּא יהוה הַצְלִיחָה נָּא: אָנָּא יהוה עֲנֵנוּ בְיוֹם קָרְאֵנוּ. לְךָ יהוה קִוִּינוּ, לְךָ יהוה חִכִּינוּ, לְךָ יהוה נְיַחֵל, אַל תֶּחֱשֶׁה וּתְעַנֵּנוּ, כִּי נַאֲמוּ גוֹיִם: אָבְדָה תִקְוָתָם. כָּל בֶּרֶך לְךָ תִּכְרַע, וְכָל קוֹמָה לְפָנֶיךָ תִּשְׁתַּחֲוֶה.\n\nהַפּוֹתֵחַ יָד בִּתְשׁוּבַה לְקַבֵּל פּוֹשְׁעִים וְחַטָּאִים, נִבְהֲלָה נַפְשֵׁנוּ מֵרֹב עִצְּבוֹנֵנוּ. אַל תִּשְׁכָּחֵנוּ נֶצַח, קוּמָה וְהוֹשִׁיעֵנוּ. אַל תִּשְׁפֹּך חֲרוֹנְךָ עָלֵינוּ, כִּי עַמְּךָ אֲנַחְנוּ בְּנֵי בְרִיתֶךָ. אֵל, הַבִּיטָה, דַּל כְּבוֹדֵנוּ בַּגּוֹיִם וְשִׁקְּצוּנוּ כְּטֻמְאַת הַנִּדָּה. עַד מַתָּי עֻזְּךָ בַשְּׁבִי, וְתִפְאַרְתְּךָ בְיַד צָר? הֵמָה יִרְאוּ וְיֵבֹשׁוּ וְיֵחַתּוּ מִגְּבוּרָתָם. עוֹרְרָה גְבוּרָתֶךָ, וְהוֹשִׁיעֵנוּ לְמַעַן שְׁמֶךָ. אַל יִמְעֲטוּ לְפָנֶיךָ תְּלָאוֹתֵינוּ, מַהֵר יְקַדְּמוּנוּ רַחֲמֶיךָ בְּעֵת צָרוֹתֵינוּ. לֹא לְמַעֲנֵנוּ, אֶלָּא לְמַעַנְךָ פְעֹל, וְאַל תַּשְׁחִית אֶת זֵכֶר שְׁאֵרִיתֵנוּ, כִּי לְךָ מְיַחֲלוֹת עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה. וּזְכֹר לָנוּ עֵדוּתֵנוּ בְכָל יוֹם תָּמִיד אוֹמְרִים פַּעֲמַיִם בְּאַהֲבָה: \"שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:\"","cond":["shacharitTachanun","17tammuz"]},{"kind":"header","text":"סליחות לעשרה בטבת","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"סליחות לעשרה בטבת","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"וָאָרֶץ שָׁפַל רוּמִי, וְגָדַל שִׁבְרִי, מְשׁוֹמֵם אֵשֵׁב, יוֹם סָמַךְ הָאֲרִי, עַל צְבִי הַר קֹדֶשׁ צִיּוֹן עִירִי, לָכֵן אֲקוֹנֵן וְאֶתְאַבֵּל בַּחֹדֶשׁ הָעֲשִׂירִי.\n\nבַּחֹדֶשׁ הָעֲשִׂירִי אַרְיֵה עָלָה בְחֵמָה, בֶּעָשׂוֹר לַחֹדֶשׁ בָּנָה עָלַי חוֹמָה, גָּשׁ הוּא וְכל-עַמּוֹ לַעֲשׂוֹת בְּעַמִּי נְקָמָה, וַיַּעַרְכוּ אִתָּם מִלְחָמָה. מִלְחָמָה שִׁית מִשְׂגַּבִּי וּמוֹשִׁיעִי, בְּאוֹיבִי וּמַכְנִיעִי, כּוֹס מָלֵא מֶסֶךְ הַשְׁקֵם יהוה רוֹעִי, מָגִּנִּי וְקֶרֶן יִשְׁעִי.\n\nבַּחֹדֶשׁ הָעֲשִׂירִי דְּלָקַנִי אוֹיֵב בַּחֶרֶב, בֶּעָשׂוֹר לַחֹדֶשׁ הֵכִין עָלַי אוֹרֵב, וְעַל זֹאת אֲקוֹנֵן וְגִילִי עָרֵב, אוֹי לָנוּ כִּי פָנָה הַיּוֹם, כִּי יִנָּטוּ צִלְלֵי-עָרֶב. עֶרֶב יֵהָפֵךְ לְבֹקֶר וּבוֹגְדִים אַל יַעֲלוּ עָל, חֹן עַל עַמְּךָ וְלִכְאֵבָם הַעֲלֵה תַעַל, זְכֹר-לִי בְּרִית אָבוֹת, בְּפָּרְשִׂי לְךָ כַּף וְשַׁעַל, מֵמִית וּמְחַיֶּה, מוֹרִיד שְׁאוֹל וַיָּעַל:\n\nבַּחֹדֶשׁ הָעֲשִׂירִי זְאֵב עֲרָבוֹת עַל עַמִּי נוֹהֵם, בֶּעָשׂוֹר לַחֹדֶשׁ חָנָה בְחֵילוֹ עֲלֵיהֶם, טָרֹף טֹרַף כָּל-הַיּוֹצֵא מֵהֶם, נָמֵר שֹׁקֵד עַל עָרֵיהֶם. עָרֵיהֶם שָׂרְפוּ בָאֵשׁ בִּרְבוֹת תְּלָאוֹת, רוּמָה יהוה בְּעֻזֶּךָ זֵדִים להַשְׁאוֹת, בּוֹשׁ יֵבוֹשׁוּ בַּעֲשׂוֹתְךָ עִמָּנוּ לְטוֹבָה אוֹת, קְדוֹשׁ יִשְׂרָאֵל יהוה צְבָאוֹת.\n\nבַּחֹדֶשׁ הָעֲשִׂירִי יְדֵי צַר הֶחֱזִיקוּ מָגֵן וְצִנָּה, בֶּעָשׂוֹר לַחֹדֶשׁ כְּאִישׁ עָרוּךְ לַמִּלְחָמָה עַל קִרְיָה נֶאֱמָנָה, לְזֹאת חִגְרִי שַׂק עֵדָה עֲדִינָה, גָּזִּי נִזְרֵךְ וְהַשְׁלִיכִי, וּשְׂאִי עַל שְׁפָיִם קִינָה. קִינָה דוֹבֵר עַמְּךָ בְּיוֹם זֶה לְעֻמָּתֶךָ, וְעַפְעַפֵּינוּ יִזְּלוּ מַיִם עַל חָרְבָּן בֵּיתֶךָ, יוֹם נָקָם תָּעִיר לַצָּרִים הוֹמִים בְּבֵיתֶךָ, דְּרָכֶיךָ יהוה הוֹדִיעֵנִי וְלַמְּדֵנִי אוֹרְחוֹתֶיךָ.\n\nבַּחֹדֶשׁ הָעֲשִׂירִי מֹנַי שָׁפְכוּ עַל עִירִי סוֹללָה, בֶּעָשׂוֹר לַחֹדֶשׁ נִזְרִי הָשְׁלַךְ וְתִפְאַרְתִּי נָפְלָה, סְבָבוּנִי הָעֹשִׂים מַכָּתִי נַחְלָה, מֵעַי מֵעַי אוֹחִילָה. אוֹחִילָה יוֹם זֶה לְנַעֲרָץ בְּסוֹד קְדוֹשִׁים רַבָּה, וַאֲחַלֶּה פָנָיו לַעֲבֹר עַל פֶּשַׁע וְחוֹבָה, אַל תֵּפֶן לְרִשְׁעֵנוּ וּמְחֵה חַטָּאת כְּתוּבָה, הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה.\n\nעַל יְדֵי רַחֲמֶיךָ הָרַבִּים סְלַח לָנוּ אָבִינוּ, כִּי בְרוֹב אִוַּלְתֵּנוּ שָׁגִינוּ, מְחֹל לָנוּ מַלְכֵּנוּ, כִּי רַבּוּ עֲוׂנֵינוּ, אֵל אֶרֶךְ אַפַּיִם אַתָּה, וְדֶרֶךְ תְּשׁוּבָה לָנוּ הוֹרֵיתָ, גְּדֻלַּת רַחֲמֶיךָ וַחֲסָדֶיךָ, תִּזְכֹּר הַיּוֹם לְזֶרַע יְדִידֶיךָ, תֵּפֶן אֵלֵינוּ בְּרַחֲמִים, כִּי אַתָּה הוּא בַּעַל הָרַחֲמִים. בְּתַחֲנוּן וּבִתְפִלָּה נְקַדֵּם, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָו מִקֶּדֶם, וּמֵחֲרוֹן אַפְּךָ תָּשׁוּב, כְּמוֹ בְּתוֹרָתְךָ כָּתוּב, וּבְצֵל כְּנָפֶיךָ נֶחֱסֶה וְנִתְלוֹנָן, כְּיוֹם וַיֵּרֶד יהוה בֶּעָנָן, תַּעֲבוֹר עַל פֶּשַׁע וְתִמְחֹל אָשָׁם, כְּיוֹם וַיִּתְיַצֵּב עִמּוֹ שָׁם, תַּאֲזִין שֶׁוַע וְתַּקְשִׁיב בְּרָצוֹן מַאֲמַר, כְּיוֹם וַיִּקְרָא בְשֵׁם, יהוה, וְשָׁם נֶאֱמַר:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אָז בּבוֹא יוֹם פְּקֻדַּת גֵּיא הַמַּחֲזֶה, בַּחֲרוֹת אַף יהוה בְּרִשְׁפֵּי אַזֶּה, גִּלָּה בְּיַד בֶּן-בּוּזִי הַחוֹזֶה: \"כְּתָב-לְךָ אֶת-שֵׁם הַיּוֹם, אֶת-עֶצֶם הַיּוֹם הַזֶּה\". דִּבַּרְתִּי בְּאֵשׁ קִנְאָתִי בֵּית מְרִי לִסְפּוֹת, הִנְנִי אֵלֶיהָ בְּאַף וְרוּחַ זִלְעָפוֹת, וְשַׂמְתִּיהָ לְמָשָׁל וְלִשְׁנִינָה וְלַחֲרָפוֹת, שְׁפֹת הַסִּיר שְׁפֹת. זַלְעָפָה אָחֲזָה צִיּוֹן וְהֵיכָלֶיהָ, חָרְדָה רוּחָהּ נָמוֹגוּ חֲיָלֶיהָ, טֹרַף לִבָּהּ עֵת קְרֹא אֵלֶיהָ, אֱסֹף נְתָחֶיהָ אֵלֶיהָ. יְרִיבֶיהָ אַעֲנִיק שְׁבִי וּמַלְקֹחַ, כֹּהֲנֶיהָ וּמֶרְקָחֶיהָ אֲשֶׁר רָקְחָה רָקֹחַ, לִשְׁבִי עוֹלָם מֵאֵין פְּקַח קֹחַ, מִבְחַר הַצֹּאן לָקֹחַ. מָשְׁלוּ בָךְ לָעֲגוּ מוֹשֶׁלֶת עַמִּים, נִקְרֵאת אָז נוֹדַעַתְ, מְאוּסַת עוֹלָמִים, שׂוֹטְנִים יַעֲנוּ בָךְ וְעָלַיִךְ נוֹאֲמִים, אוֹי עִיר הַדָּמִים. עָבְרָה עֲבֵרָה סָרָה הֵפֵרָה בְּרִית יָהּ, פָּשְׁעָה רָשְׁעָה טָבְעָה בְּבוֹר תַּחְתִּיָּה, צָעֲקָה וְלֹא שָׁמַע אֵל בִּכְיָהּ, כִּי דָמָהּ בְּתוֹכָהּ הָיָה. קוֹל עֲשׁוּקֶיהָ שְׁמַע מִיַּד עוֹשְׁקָם, רִגְשָׁתָם וְצַוְחָתָם לֹא תָשִׁיב רֵיקָם, שִׁבְעָתַיִם תְּשַׁלֵּם כְּפָעֳלָם אֶל חֵיקָם, שֶׁבַע יִפֹּל צַדִּיק וָקָם. תָּעִינוּ בְרִשְׁעֵנוּ אֵל גָּדוֹל וְנוֹרָא, וְאִם גָּבְרוּ פְשָׁעֵינוּ חֶמְלָתְךָ גָבְרָה, רִחַמְתָּ וְכִמְעַט קָט כִּלִּיתָם בְּעֶבְרָה, צָרָה וְיָגוֹן אֶמְצָא וּבְשֵׁם יהוה אֶקְרָא. יֶהֱמוּ רַחֲמֶיךָ עַל מְעוּטֵי עַמִּים, וְשַׂגְּבֵם בְּחַסְדְּךָ לְעֵינֵי כָל-לְאֻמִּים, פְּלָאֶיךָ הַרְאֵם צוּר שׁוֹכֵן מְרוֹמִים, אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים.\n\nשְׁעֵה עֶלְיוֹן, לְקוֹל אֶבְיוֹן, וְשַׁוְעָתוֹ אַל תִּבְזֶה. לְבָבוֹ מַר, בְּיוֹם נֶאֱמַר, לְבֶן בּוּזִי הַחוֹזֶה: \"כְּתָב-לְךָ אֶת-שֵׁם הַיּוֹם, אֶת-עֶצֶם הַיּוֹם הַזֶּה\". יָהּ צְבָאוֹת, זְכֹר תְּלָאוֹת, אֲשֶׁר צַר לִי מאֹד עֲלֵיהֶן. בְּמַזַּל גְּדִי, הֲלֹא בַעֲדִי, נֶאֶסְפוּ שְׁלָשְׁתֵּיהֶן. וּבוֹ שֵׂיוֹת, הַדּחוּיוֹת, חַל הַנֶּגֶף בָּהֶן. וּבוֹ סָמַךְ, מְנָאֵץ שְׁמָךְ, עַל קִרְיַת מְשׂוֹשֵׂיהֶן. וּבוֹ נֶאֱסַף רֹאשׁ הַסָּף, הוּא עֶזְרָא הַכֹּהֵן. כָּל-אֵלֶּה קְרָאוּנִי, וְרַבּוֹת כָּזֶה וְכָזֶה. אֲרִי עָלַז, בְּיוֹם הַלָּז, וְחֵץ קִלְקֵל לְמוּל עִירִי. וְקָם עֲשִׂירִי, בָּעֲשִׂירִי, לְשַׁחֵת כָּל-שְׁאָר הָעֲשִׂירִי. לְאַבֵּד כֹּל, פְּרִי אֶשְׁכֹּל, וְלִלְקוֹט עִנְּבֵי נְזִירִי. וְעוֹד קָשׁוּר, אֲנִי לְאַשּׁוּר, אֲשֶׁר נִצָּב עַל צִירִי. אֲנִי נִגְדָּע, וְלֹא אֵדַע, לְמִי אֶבְכֶּה הֲזֶה אוֹ זֶה. סְמֹךְ עַמָּךְ, בְּיוֹם סָמַךְ, אֲרִי עַל עִיר צְבִי קֹדֶשׁ. שְׁעֵה שַׁוְעָם, מְחֵה פִשְׁעָם, בֶּעָשׂוֹר לַחֹדֶשׁ. וְהַמְּלוּכָה, הַנְּסוּכָה, כִּימֵי קֶדֶם חַדֵּשׁ. וְלִתְהִלָּה, כְּבַתְּחִלָּה, שִׁמְךָ יָהּ בָּנוּ קַדֵּשׁ. וְכָל-שׂוֹנֵא, וּמִתְאַנֶּה, בְּעֹז אַפְּךָ הָדֵּשׁ. וְיִלָּכדוּ, וְיֹאבדוּ, כְּיוֹם בָּרָק בְּעִיר קֶדֶשׁ. וְשׁוּב עֶלְיוֹן, לְעִיר צִיּוֹן, עַיִן בְּעַיִן נֶחֱזֶה. וְאָז נֹאמַר, בְּטוּב מַאֲמָר, הִנֵּה אֱלֹהֵינוּ זֶה.\n\nיוֹשֵׁב בַּשָּׁמַיִם, שְׁעֵה בָּאֵי בָאֵשׁ וּבַמָּיִם. וְחֹן עַל עַם אֲשֶׁר לָקוּ בְּחַטֹּאתָם כִּפְלָיִם. בְּיוֹם הֵחֵל צַר לָצוּר מְחוֹלַת מַחֲנַיִם, סָמַךְ מֶלֶךְ בָּבֶל אֶל יְרוּשָׁלָיִם. הָעוֹנֶה בַּמֵּצָר, עֱנוּת עָנִי אַל תִּבְזֶה. בְּיוֹם צוֹם הָעֲשִׂירִי, עֱנוּתֵנוּ תֶּחֱזֶה. יוֹם הִזְהַרְתָּ בַּמַּחֲזֶה, לְבֶן-בּוּזִי הַחוֹזֶה: \"כְּתָב-לְךָ אֶת-שֵׁם הַיּוֹם, אֶת-עֶצֶם הַיּוֹם הַזֶּה\". יוֹם בּוֹ שָׁקַד שַׁחַל, וְנָמֵר עַל דְּלַתָיִם. יוֹם סָמּכוּ עַל אַרְמוֹן נַחֲלַת צְבִי וָשֶׁפֶר, וּבוֹ הוּחַל הַנֶּגֶף בְּמַכְפִּישֵׁי בָּאֵפֶר. וְגַם בּוֹ נֶאֱסַף, עֶזְרָא הַכֹּהֵן הַסּוֹפֵר. וְלֵב מְתֵי קִרְיַת סֵפֶר, בּוֹ הָיָה לְמָיִם, סָמַךְ מֶלֶךְ בָּבֶל אֶל יְרוּשָׁלָיִם.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, וּמִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לַחַטָּאִים, וּסְלִיחָה לַפּוֹשְׁעִים. עוֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וְרוּחַ, לֹא כְרָעָתָם לָהֶם גּוֹמֵל. אֵל, הוֹרֵתָנוּ לוֹמַר מִדּוֹת שְׁלֹשׁ עֶשְׂרֵה, זְכֹר לָנוּ הַיּוֹם בְּרִית שְׁלֹשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָו מִקֶּדֶם, וְכֵן כָּתוּב בְּתוֹרָתָךְ: וַיֵּרֶד יהוה בֶּעָנָן וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם יהוה: וְשָׁם נֶאֱמַר:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אַנְשֵׁי אֱמוּנָה אָבָדוּ, בָּאִים בְּכֹחַ מַעֲשֵׂיהֶם. גִּבּוֹרִים לַעֲמֹד בַּפֶּרֶץ, דּוֹחִים אֶת-הַגְּזֵרוֹת. הָיוּ לָנוּ לְחוֹמָה, וּלְמַחְסֶה בְּיוֹם זָעַם. זוֹעֲכִים אַף בְּלַחֲשָׁם, חֵמָה עָצרוּ בְּשַׁוְּעָם. טֶרֶם קְרָאוּךָ עֲנִיתָם, יוֹדְעִים לַעֲתֹר וּלְרַצּוֹת. כְּאָב רִחַמְתָּ לְמַעֲנָם, לֹא הֱשִׁיבוֹתָ פְנֵיהֶם רֵיקָם. מֵרֹב עֲוׂנֵינוּ אֲבַדְנוּם, נֶאֶסְפוּ מֶנּוּ בַּחֲטָאֵינוּ. סָעוּ הֵמָּה לִמְנוּחוֹת, עָזבוּ אוֹתָנוּ לַאֲנָחוֹת. פַּסּוּ גוֹדְרֵי גָדֵר, צֻמְּתוּ מְשִׁיבֵי חֵמָה. קָמִים בַּפֶּרֶץ אַיִן, רְאוּיִים לְרַצּוֹתְךָ אָפֵסוּ. שׁוֹטַטְנוּ בְּאַרְבַּע פִּנּוֹת, תְּרוּפָה לֹא מָצָאנוּ. שַׁבְנוּ אֵלֶיךָ בּבֹשֶׁת פָּנֵינוּ, לשַׁחֲרָךְ אֵל בְּעֵת צָרוֹתֵינוּ.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, וּמִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לַחַטָּאִים, וּסְלִיחָה לַפּוֹשְׁעִים. עוֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וְרוּחַ, לֹא כְרָעָתָם לָהֶם גּוֹמֵל. אֵל, הוֹרֵתָנוּ לוֹמַר מִדּוֹת שְׁלֹשׁ עֶשְׂרֵה, זְכֹר לָנוּ הַיּוֹם בְּרִית שְׁלֹשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָו מִקֶּדֶם, וְכֵן כָּתוּב בְּתוֹרָתָךְ: וַיֵּרֶד יהוה בֶּעָנָן וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם יהוה: וְשָׁם נֶאֱמַר:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"תָּמַהְנוּ מֵרָעוֹת, תָּשַׁשׁ כֹּחֵנוּ מִצָּרוֹת. שַׁחְנוּ עַד לִמְאֹד, שָׁפַלְנוּ עַד עָפָר. רַחוּם כָּךְ הִיא מִדָּתֵנוּ, קְשֵׁי עֹרֶף וּמַמְרִים אֲנַחְנוּ. צָעַקְנוּ בְּפִינוּ חָטָאנוּ, פְּתַלְתּוֹל וְעִקֵּשׁ לִבֵּנוּ. עֶלְיוֹן, רַחֲמֶיךָ מֵעוֹלָם, סְלִיחָה עִמְּךָ הִיא. נִחָם עַל הָרָעָה, מַטֵּה כְלַפֵּי חֶסֶד. לֹא תִתְעַלַּם בְּעִתּוֹת כָּאֵל, כִּי בְצָרָה גְדוֹלָה אֲנָחְנוּ. יִוָּדַע לְעֵינֵי הַכֹּל, טוּבְךָ וְחַסְדְּךָ עִמָּנוּ. חֲתֹם פִּי-שָׂטָן, וְאַל יַשְׂטִין עָלֵינוּ, זְעֹם בּוֹ ויִדֹּם. וְיַעֲמֹד מֵלִיץ טוֹב לְצַדְּקֵנוּ, הוּא יַגִּיד יָשְׁרֵנוּ. דְּרָכֶיךָ רַחוּם וְחַנּוּן גִּלִּיתָ לְנֶאֱמַן בָּיִת. בְּבַקְשׁוֹ אָז מִלּפָנֶיךָ, אֱמוּנָתךָ הוֹדַעְתָּ לּוֹ.","cond":["shacharitTachanun","10tevet"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, וּמִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לַחַטָּאִים, וּסְלִיחָה לַפּוֹשְׁעִים. עוֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וְרוּחַ, לֹא כְרָעָתָם לָהֶם גּוֹמֵל. אֵל, הוֹרֵתָנוּ לוֹמַר מִדּוֹת שְׁלֹשׁ עֶשְׂרֵה, זְכֹר לָנוּ הַיּוֹם בְּרִית שְׁלֹשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָו מִקֶּדֶם, וְכֵן כָּתוּב בְּתוֹרָתָךְ: וַיֵּרֶד יהוה בֶּעָנָן וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם יהוה: וְשָׁם נֶאֱמַר:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"וּכְשֶׁחָטאוּ יִשְׂרָאֵל בַּמִּדְבָּר, עָמַד מֹשֶׁה בִּתְפִלָּה לְפָנֶיךָ, וּבִקֵּשׁ רַחֲמִים עַל עַמְּךָ יִשְׂרָאֵל וְכָךְ אָמַר בִּתְפִלָּתוֹ: סְלַח-נָא לַעֲוׂן הָעָם הַזֶּה כְּגֹדֶל חַסְדֶּךָ, וְכַאֲשֶׁר נָשָׂאתָה לָעָם הַזֶּה מִמִּצְרַיִם וְעַד-הֵנָּה: אַף אַתָּה הֱשִׁיבוֹתָ לוֹ כְּדַרְכֵי טוּבְךָ בִּשַּׂרְתּוֹ וַחֲנַנְתּוֹ וְאָמַרְתָּ לוֹ: סָלַחְתִּי כִּדְבָרֶךָ:\n\nדָּנִיֵּאל אִישׁ חֲמוּדוֹת אָמַר לְפָנֶיךָ: הַטֵּה אֱלֹהַי אָזְנְךָ וּשֲׁמָע, פְּקַח עֵינֶיךָ וּרְאֵה שֹׁמְמֹתֵינוּ וְהָעִיר אֲשֶׁר-נִקְרָא שִׁמְךָ עָלֶיהָ, כִּי לֹא עַל-צִדְקֹתֵינוּ אֲנַחְנוּ מַפִּילִים תַּחֲנוּנֵינוּ לְפָנֶיךָ, כִּי עַל-רַחֲמֶיךָ הָרַבִּים: אֲדֹנָי שְׁמָעָה, אֲדֹנָי סְלָחָה, אֲדֹנָי הַקְשִׁיבָה וַעֲשֵׂה אַל-תְּאַחַר, לְמַעֲנְךָ אֱלֹהַי כִּי-שִׁמְךָ נִקְרָא עַל-עִירְךָ וְעַל עַמֶּךָ: וְלִירוּשָׁלַיִם עִירָךְ אָמַרְתָּ לָהּ: הִנְנִי נִשְׁפָּט אוֹתָךְ עַל-אָמְרֵךְ לֹא חָטָאתִי: אֲנַחְנוּ בּוֹשְׁנוּ בְּמַעֲשֵׂינוּ וְנִכְלַמְנוּ בַּעֲוׂנוֹתֵינוּ, אֵין לָנוּ פֶּה לְהָשִׁיב וְלֹא מֵצַח לְהָרִים רֹאשׁ.\n\nאֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אַל תַּעַשׂ עִמָּנוּ כָּלָה, תֹּאחֵז יָדְךָ בַּמִּשְׁפָּט. בְּבֹא תוֹכֵחָה נֶגְדֶּךָ, שְׁמֵנוּ מִסִּפְרְךָ אַל תֶּמַח. גִּשְׁתְּךָ לַחֲקֹר מוּסָר, רַחֲמֶיךָ יְקַדְּמוּ רָגְזֶךָ. דַּלּוּת מַעֲשִׂים בְּשׁוּרֶךָ, קָרֵב צֶדֶק מֵאֵלֶיךָ. הוֹרֵנוּ, בְּזַעֲקֵנוּ לָךְ, צַו יְשׁוּעָתֵנוּ בְּמַפְגִּיעַ. וְתָשִׁיב שְׁבוּת אָהֳלֵי תָם, פְּתָחָיו רְאֵה כִּי שָׁמֵמוּ. זְכֹר נָאַמְתָּ, עֵדוּת לֹא תִשָּׁכַח מִפִּי זַרְעוֹ. חוֹתַם תְּעוּדָה תַּתִּיר, סוֹדְךָ שִׂים בְּלִמּוּדֶיךָ. טַבּוּר אַגַּן הַסַּהַר, נָא אַל יֶחְסַר הַמָּזֶג. יָהּ, דַּע אֶת-יִשְׂרָאֵל אֲשֶׁר יְדָעוּךָ, מַגֵּר אֶת-הַגּוֹיִם אֲשֶׁר לֹא יְדָעוּךָ. כִּי תָשִׁיב לְבִצָּרוֹן, לְכוּדִים אֲסִירֵי הַתִּקְוָה.\n\nאָשַׁמְנוּ מִכָּל-עָם, בֹּשְׁנוּ מִכָּל-גּוֹי. גָּלָה מִמֶּנּוּ מָשׂוֹשׂ, דָּוֶה לִבֵּנוּ בַּחֲטָאֵינוּ. הָחְבַּל אֶוְיֵינוּ, וְנִפְרָע פְּאֵרֵנוּ. זְבוּל מִקְדָּשֵׁנוּ, חָרֵב בַּעֲוֹנֵינוּ. טִירָתֵנוּ הָיְתָה לְשַׁמָּה, יְפִי אַדְמָתֵנוּ לְזָרִים, כֹּחֵנוּ לְנָכְרִים. לְעֵינֵינוּ עָשְׁקוּ עֲמָלֵנוּ, מְמֻשָּׁךְ וּמוֹרָט מִמֶּנּוּ. נָתְנוּ עֻלָּם עָלֵינוּ, סָבַלְנוּ עַל שִׁכְמֵנוּ. עֲבָדִים מָשְׁלוּ בָנוּ, פּוֹרֵק אֵין מִיָּדָם. צָרוֹת רַבּוֹת סְבָבוּנוּ, קְרָאנוּךָ יהוה אֱלֹהֵינוּ. רָחַקְתָּ מִמֶּנּוּ בַּעֲוׂנֵינוּ, שַׁבְנוּ מֵאַחֲרֶיךָ, תָּעִינוּ כַּצֹּאן וְאָבָדְנוּ. וַעֲדַיִן לֹא שַׁבְנוּ מִתְּעִיָּתֵנוּ, וְהֵיאַךְ נָעִיז פָּנֵינוּ, וְנַקְשֶׁה עָרְפֵּנוּ, לוֹמַר לְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ צַדִּיקִים אֲנַחְנוּ וְלֹא-חָטָאנוּ.\n\nעֶזְרָא הַסּוֹפֵר אָמַר לְפָנֶיךָ: אֱלֹהַי, בֹּשְׁתִּי וְנִכְלַמְתִּי לְהָרִים אֱלֹהַי פָּנַי אֵלֶיךָ, כִּי עֲוׂנֹתֵינוּ רָבוּ לְמַעְלָה רֹאשׁ, וְאַשְׁמָתֵנוּ גָדְלָה עַד לַשָּׁמָיִם: וְאַתָּה אֱלוֹהַּ סְלִיחוֹת, חַנּוּן ורַחוּם, אֶרֶךְ-אַפַּיִם וְרַב-חֶסֶד, וְלֹא עֲזַבְתָּם. אַל תַּעַזְבֵנוּ אָבִינוּ, אַל תִּטְּשֵׁנוּ מַלְכֵּנוּ, וְאַל תִּשְׁכָּחֵנוּ יוֹצְרֵנוּ, וְאַל תַּעַשׂ עִמָּנוּ כָלָה בְּגָלוּתֵנוּ, וְקַיֵּם לָנוּ יהוה אֱלֹהֵינוּ אֶת-הַדָּבָר שֶׁהִבְטַחְתָּנוּ, עַל יְדֵי יִרְמְיָה חוֹזָךְ, כָּאָמוּר: בַּיָּמִים הָהֵם וּבָעֵת הַהִיא, נְאֻם-יהוה, יבֻקַּשׁ אֶת-עֲוׂן יִשְׂרָאֵל וְאֵינֶנּוּ, וְאֶת-חַטֹּאת יְהוּדָה וְלֹא תִמָּצֶאנָה, כִּי אֶסְלַח לַאֲשֶׁר אַשְׁאִיר: וְאַל יעַכֵּב לפָנֶיךָ כָּל-חֵטְא וְעוׂן אֶת תְּפִלָּתֵנוּ, וּמְחוֹל וּסְלַח לְכָל-עֲוׂנוֹתֵינוּ, כִּי אֵל טוֹב וסַלָּח אָתָּה.\n\nמַה-נֹּאמַר לְפָנֶיךָ יוֹשֵׁב מָרוֹם, וּמַה נְּסַפֵּר לְפָנֶיךָ שׁוֹכֵן שְׁחָקִים, הֲלֹא הַנִּסְתָּרוֹת והַנִּגְלוֹת אַתָּה יוֹדֵעַ, אַתָּה יוֹדֵעַ רָזֵי עוֹלָם, וְתַעֲלוּמוֹת סִתְרֵי כָל-חָי, אַתָּה חוֹפֵשׂ כָּל-חַדְרֵי בָטֶן, רֹאֶה כלָיוֹת וָלֵב. אֵין דָּבָר נֶעְלָם מִמָּךְ, וְאֵין נִסְתָּר מִנֶּגֶד עֵינֶיךָ.\n\nיְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּמְחֹל לָנוּ אֶת-כָּל-חַטֹּאתֵינוּ, וּתְכַפֵּר לָנוּ אֶת-כָּל-עֲוׂנוֹתֵינוּ, וְתִמְחֹל וְתִסְלַח לכָל-פְּשָׁעֵינוּ, וְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ: סְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחֹל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי, טוֹב וְסַלָּח, וְרַב-חֶסֶד לְכָל-קֹרְאֶיךָ: לְמַעַן-שִׁמְךָ יהוה, וְסָלַחְתָּ לַעֲוׂנִי כִּי רַב-הוּא: לְמַעַן-שִׁמְךָ יהוה תְּחַיֵּנִי, בְּצִדְקָתְךָ תוֹצִיא מִצָּרָה נַפְשִׁי: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב-לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה: יהוה צְבָאוֹת, אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם-קָרְאֵנוּ: הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם:","cond":["shacharitTachanun","10tevet"]},{"kind":"text","text":"וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית, וְהִרְבָּה לְהָשִׁיב אַפּוֹ וְלֹא יָעִיר כָּל חֲמָתוֹ: אַתָּה יהוה, לֹא תִכְלָא רַחֲמֶיךָ מִמֶּנִּי, חַסְדְּךָ וַאֲמִתְּךָ תָּמִיד יִצְּרוּנִי: הוֹשִׁיעֵנוּ יהוה אֱלֹהֵינוּ וְקַבְּצֵנוּ מִן הַגּוֹיִם, לְהֹדוֹת לְשֵׁם קָדְשֶׁךָ, לְהִשְׁתַּבֵּחַ בִּתְהִלָּתֶךָ: אִם עֲוׂנוֹת תִּשְמָר יָהּ, אֲדֹנָי, מִי יַעֲמֹד: כִּי עִמְּךָ הַסְּלִיחָה, לְמַעַן תִּוָּרֵא: לֹא כַחֲטָאֵינוּ עָשָׂה לָנוּ, וְלֹא כַעֲוׂנֹתֵינוּ גָמַל עָלֵינוּ. אִם עֲוׂנֵינוּ עָנוּ בָנוּ, יהוה, עֲשֵׂה לְמַעַן שְׁמֶךָ. זְכֹר רַחֲמֶיךָ יהוה וַחֲסָדֶיךָ, כִּי מֵעוֹלָם הֵמָּה: יַעַנְךָ יהוה בְּיוֹם צָרָה, יְשַׂגֶּבְךָ שֵׁם אֱלֹהֵי יַעֲקֹב: יהוה הושִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ: אָבִינוּ מַלְכֵּנוּ, חָנֵּנוּ וַעֲנֵנוּ, כִּי אֵין בָּנוּ מַעֲשִׂים. עֲשֵׂה עִמָּנוּ צְדָקָה כְּרֹב רַחֲמֶיךָ, וְהוֹשִׁיעֵנוּ לְמַעַן שְׁמֶךָ.\n\nוְעַתָּה אֲדֹנָי אֱלֹהֵינוּ אֲשֶׁר הוֹצֵאתָ אֶת עַמְּךָ מֵאֶרֶץ מִצְרַיִם בְּיָד חֲזָקָה, וַתַּעַשׂ לְךָ שֵׁם כַּיּוֹם הַזֶּה, חָטָאנוּ רָשָׁעְנוּ: אֲדֹנָי, כְּכָל צִדְקֹתֶךָ יָשָׁב נָא אַפְּךָ וַחֲמָתְךָ מֵעִירְךָ יְרוּשָׁלַיִם הַר קָדְשֶׁךָ, כִּי בַחֲטָאֵינוּ וּבַעֲוׂנוֹת אֲבֹתֵינוּ, יְרוּשָׁלִַם וְעַמְּךָ לְחֶרְפָּה לְכָל סְבִיבֹתֵינוּ: וְעַתָּה שְׁמַע אֱלֹהֵינוּ אֶל תְּפִלַּת עַבְדְּךָ וְאֶל תַּחֲנוּנָיו, וְהָאֵר פָּנֶיךָ עַל מִקְדָּשְׁךָ הַשָּׁמֵם, לְמַעַן אֲדֹנָי: הַטֵּה אֱלֹהַי אָזְנְךָ וּשְׁמָע, פְּקַח עֵינֶיךָ וּרְאֵה שֹׁמְמֹתֵינוּ וְהָעִיר אֲשֶׁר נִקְרָא שִׁמְךָ עָלֶיהָ, כִּי לֹא עַל צִדְקֹתֵינוּ אֲנַחְנוּ מַפִּילִים תַּחֲנוּנֵינוּ לְפָנֶיךָ, כִּי עַל רַחֲמֶיךָ הָרַבִּים: אֲדֹנָי שְׁמָעָה, אֲדֹנָי סְלָחָה, אֲדֹנָי הַקֲשִׁיבָה וַעֲשֵׂה אַל תְּאַחַר, לְמַעֲנְךָ אֱלֹהַי, כִּי שִׁמְךָ נִקְרָא עַל עִירְךָ וְעַל עַמֶּךָ:\n\nאָבִינוּ אָב הָרַחֲמָן, הַרְאֵנוּ אוֹת לְטוֹבָה וְקַבֵּץ נְפוּצוֹתֵינוּ מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ. יַכִּירוּ וְיֵדְעוּ כָּל הַגּוֹיִם, כִּי אַתָּה יהוה אָבִינוּ אָתָּה, אֲנַחְנוּ הַחֹמֶר וְאַתָּה יֹצְרֵנוּ וּמַעֲשֵׂה יָדְךָ כֻּלָּנוּ: אָבִינוּ מַלְכֵּנוּ, צוּרֵנוּ מַלְכֵּנוּ וְגוֹאֲלֵנוּ, חוּסָה יהוה עַל עַמֶּךָ וְאַל תִּתֵּן נַחֲלָתְךָ לְחֶרְפָּה לִמְשָׁל בָּם גּוֹיִם, לָמָּה יֹאמְרוּ בָעַמִּים אַיֵּה אֱלֹהֵיהֶם: יָדַעְנוּ יהוה כִּי חָטָאנוּ וְאֵין מִי יַעֲמֹד בַּעֲדֵנוּ, אֶלָּא שִׁמְךָ הַגָּדוֹל יַעֲמָד לָנוּ בְּעֵת צָרָה. וּכְרַחֵם אָב עַל בָּנִים רַחֵם עָלֵינוּ. חֲמֹל עַל עַמָּךְ וְרַחֵם עַל נַחֲלָתָךְ, חוּסָה נָּא כְּרֹב רַחֲמֶיךָ, חָנֵנוּ מַלְכֵּנוּ וַעֲנֵנוּ. לְךָ יהוה הַצְּדָקָה, עֹשֵׂה נִפְלָאוֹת בְּכָל עֵת וָעֵת. הַבֵּט נָא וְהוֹשִׁיעָה נָּא צֹאן מַרְעִיתֶךָ. אַל יִמְשָׁל בָּנוּ קֶצֶף, כִּי לְךָ יהוה הַיְשׁוּעָה, בְּךָ תוֹחַלְתֵּנוּ. אֱלוֹהַּ סְלִיחוֹת, אָנָּא סְלַח נָא. כִּי אֵל טוֹב וְסַלָּח אָתָּה. אָנָּא מֶלֶךְ רַחוּם וְחַנּוּן, זְכֹר וְהַבֵּט לִבְרִית בֵּין הַבְּתָרִים, וְתֵרָאֶה לְפָנֶיךָ עֲקֵדַת יָחִיד. וּלְמַעַן יִשרָאֵל אָבִינוּ, אַל תַּעַזְבִנוּ אָבִינוּ וְאַל תִּטְּשֵנוּ מַלְכֵּנוּ, וְאַל תִּשְׁכָּחֵנוּ יוֹצְרֵנוּ, וְאַל תַּעַשׂ עִמָּנוּ כָלָה בְּגָלוּתֵנוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.\n\nאֵין כָּמוֹך חַנּוּן וְרַחוּם, אֱלֹהֵינוּ, אֵין כָּמוֹךָ אֵל אֶרֶך אַפַּיִם וְרַב חֶסֶד וֶאֱמֶת. הוֹשִׁיעֵנוּ וְרַחֲמֵנוּ, מֵרַעַשׁ וּמֵרֹגֶז הַצִּילֵנוּ. זְכֹר לַעֲבָדֶיך לְאַבְרָהָם לְיִצְחָק וּלְיַעֲקֹב, אַל תֵּפֶן אֶל קְשִׁי הָעָם הַזֶּה וְאֶל רִשְׁעוֹ וְאֶל חַטָּאתוֹ: שׁוּב מֵחָרוֹן אַפֶּךָ, וְהִנָּחֵם עַל הָרָעָה לְעַמֶּךָ: וְהָסֵר מִמֶּנּוּ מַכַּת הַמָּוֶת כִּי רַחוּם אָתָּה, כִּי כֵן דַּרְכְּךָ לַעֲשׂוֹת חֶסֶד חִנָּם בְּכָל דוֹר וָדוֹר. אָנָּא יהוה הוֹשִׁיעָה נָּא, אָנָּא יהוה הַצְלִיחָה נָּא: אָנָּא יהוה עֲנֵנוּ בְיוֹם קָרְאֵנוּ. לְךָ יהוה קִוִּינוּ, לְךָ יהוה חִכִּינוּ, לְךָ יהוה נְיַחֵל, אַל תֶּחֱשֶׁה וּתְעַנֵּנוּ, כִּי נַאֲמוּ גוֹיִם: אָבְדָה תִקְוָתָם. כָּל בֶּרֶך לְךָ תִּכְרַע, וְכָל קוֹמָה לְפָנֶיךָ תִּשְׁתַּחֲוֶה.\n\nהַפּוֹתֵחַ יָד בִּתְשׁוּבַה לְקַבֵּל פּוֹשְׁעִים וְחַטָּאִים, נִבְהֲלָה נַפְשֵׁנוּ מֵרֹב עִצְּבוֹנֵנוּ. אַל תִּשְׁכָּחֵנוּ נֶצַח, קוּמָה וְהוֹשִׁיעֵנוּ. אַל תִּשְׁפֹּך חֲרוֹנְךָ עָלֵינוּ, כִּי עַמְּךָ אֲנַחְנוּ בְּנֵי בְרִיתֶךָ. אֵל, הַבִּיטָה, דַּל כְּבוֹדֵנוּ בַּגּוֹיִם וְשִׁקְּצוּנוּ כְּטֻמְאַת הַנִּדָּה. עַד מַתָּי עֻזְּךָ בַשְּׁבִי, וְתִפְאַרְתְּךָ בְיַד צָר? הֵמָה יִרְאוּ וְיֵבֹשׁוּ וְיֵחַתּוּ מִגְּבוּרָתָם. עוֹרְרָה גְבוּרָתֶךָ, וְהוֹשִׁיעֵנוּ לְמַעַן שְׁמֶךָ. אַל יִמְעֲטוּ לְפָנֶיךָ תְּלָאוֹתֵינוּ, מַהֵר יְקַדְּמוּנוּ רַחֲמֶיךָ בְּעֵת צָרוֹתֵינוּ. לֹא לְמַעֲנֵנוּ, אֶלָּא לְמַעַנְךָ פְעֹל, וְאַל תַּשְׁחִית אֶת זֵכֶר שְׁאֵרִיתֵנוּ, כִּי לְךָ מְיַחֲלוֹת עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה. וּזְכֹר לָנוּ עֵדוּתֵנוּ בְכָל יוֹם תָּמִיד אוֹמְרִים פַּעֲמַיִם בְּאַהֲבָה: \"שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:\"","cond":["shacharitTachanun","10tevet"]},{"kind":"header","text":"סליחות לתענית אסתר","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"סליחות לתענית אזתר","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"עַל יְדֵי רַחֲמֶיךָ הָרַבִּים סְלַח לָנוּ אָבִינוּ, כִּי בְרוֹב אִוַּלְתֵּנוּ שָׁגִינוּ, מְחֹל לָנוּ מַלְכֵּנוּ, כִּי רַבּוּ עֲוׂנֵינוּ, אֵל אֶרֶךְ אַפַּיִם אַתָּה, וְדֶרֶךְ תְּשׁוּבָה לָנוּ הוֹרֵיתָ, גְּדֻלַּת רַחֲמֶיךָ וַחֲסָדֶיךָ, תִּזְכֹּר הַיּוֹם לְזֶרַע יְדִידֶיךָ, תֵּפֶן אֵלֵינוּ בְּרַחֲמִים, כִּי אַתָּה הוּא בַּעַל הָרַחֲמִים. בְּתַחֲנוּן וּבִתְפִלָּה נְקַדֵּם, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָו מִקֶּדֶם, וּמֵחֲרוֹן אַפְּךָ תָּשׁוּב, כְּמוֹ בְּתוֹרָתְךָ כָּתוּב, וּבְצֵל כְּנָפֶיךָ נֶחֱסֶה וְנִתְלוֹנָן, כְּיוֹם וַיֵּרֶד יהוה בֶּעָנָן, תַּעֲבוֹר עַל פֶּשַׁע וְתִמְחֹל אָשָׁם, כְּיוֹם וַיִּתְיַצֵּב עִמּוֹ שָׁם, תַּאֲזִין שֶׁוַע וְתַּקְשִׁיב בְּרָצוֹן מַאֲמַר, כְּיוֹם וַיִּקְרָא בְשֵׁם, יהוה, וְשָׁם נֶאֱמַר:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"אֲגָגִי בְּהַעֲמִיקוֹ מַחֲשֶׁבֶת זְמָמוֹ, בּהִוָּסְדוֹ עַל עַם קָדוֹשׁ לְאַבְּדוֹ וּלְהַחֲרִימוֹ. יְמִינִי גָּעָה בְּבִכְיָה לְצוּר שׁוֹכֵן מְרוֹמוֹ, כִּי לֹא יִטּוֹשׁ יהוה אֶת-עַמּוֹ. אֲגָגִי דִמָּה לְכַלּוֹת שְׁאֵרִית יִשְׂרָאֵל וּלְאַבְּדֵנוּ, הִפִּיל פּוּר הוּא הַגּוֹרָל בְּיוֹם זֶה לְגַדְּעֵנוּ. יְמִינִי וְלֹא קָם וְלֹא זָע מִמֶּנּוּ, וְהַבּוֹטֵחַ בַּיהוה חֶסֶד יְסוֹבבֶנּוּ: אֲגָגִי זְדוֹנוֹ הִשִּׁיאוֹ בְּעֵצָה נִבְעָרָה, חָשׁ לִשְׁקוֹל עֲשֶׂרֶת אֲלָפִים לְאַבֵּד שֶׂה פְזוּרָה. יְמִינִי טִהַר לִבּוֹ בְּצוֹם וַעֲצָרָה, טוֹב יהוה לְמָעוֹז בְּיוֹם צָרָה. אֲגָגִי יָצָא שָׂמֵחַ מִבֵּית מַעֲדַנּוֹת, כּוֹנֵן עֵץ לִתְלוֹת עָלָיו אִישׁ אֱמוּנוֹת. יְמִינִי לָבַשׁ חֵן וְנִסְמָךְ עַל עוֹטֶה גְאוֹנוֹת, אֲבִי יְתוֹמִים וְדַיַּן אַלְמָנוֹת. אֲגָגִי מִהַר קְרוֹא חֲכָמָיו וּמִדְיְנֵי אִשָּׁה, נָפֹל תִּפֹּל לְפָנָיו יְעָצוּהוּ לְבוּשָׁה. יְמִינִי סוֹד הוֹדִיעַ לַהֲדַסָּה וּמַלְכוּת לָבְשָׁה, וֶאֱסָרָהּ אֲשֶׁר אָסְרָה עַל נַפְשָׁהּ. אֲגָגִי עֵת בּוֹאוֹ לְמִשְׁתֶּה מְסִבָּה, פִּיהָ פָּתְחָה בְחָכְמָה אֲהוּבָה נְדִיבָה. יְמִינִי צָהַל בִּרְאוֹתוֹ מַפָּלַת הָמָן בְּחִבָּה, אֵל נַעֲרָץ בְּסוֹד קְדוֹשִׁים רַבָּה. קָדוֹשׁ הַנֶּעֶרָץ בְּסוֹד שַׂרְפֵי מְעוֹנַי, רוֹמְמוֹתֶךָ יִפְצְחוּ עֲדַת אֱמוּנַי, לִישׁוּעָתְךָ קִוִּיתִי יהוה: כֵּן יֹאבְדוּ כָּל-אֹיבֶיךָ יהוה. יֶהֱמוּ נָא רַחֲמֶיךָ עַל מְעוּטֵי עַמִּים, וְשַׂגְּבֵם בְּחַסְדְּךָ לְעֵינֵי כָל-לְאֻמִּים, פְּלָאֶיךָ הַרְאֵם צוּר שׁוֹכֵן מְרוֹמִים, אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים.\n\nיִחַלְתָּ עֲבָדֶיךָ בְּחֶזְיוֹנֵי כִתְבֵיהֶם, לְתִתָּם לְרַחֲמִים לִפְנֵי כָּל שׁוֹבֵיהֶם, וְדִבַּרְתָּ עַל לִבָּם לְרַפֹּאת מַכְאוֹבֵיהֶם, וְאַף גַּם זֹאת בִּהְיוֹתָם בְּאֶרֶץ אֹיְבֵיהֶם. צִמְּתַתְנִי אָז אַרְיֵה מִגֶּפֶן פּוֹרִיָּה, הִגְלָנִי וְהֶעֱלָנִי עַל אֶרֶץ מַאְפֵּליָה, הִקְדַּמְתָּ אַרְבָּעָה הוֹגֵי דַת תּוּשִׁיָּה, דָּנִיֵּאל חֲנַנְיָה מִישָׁאֵל וַעֲזַרְיָה, זֶה נִצַּל מֵאֲרָיוֹת וְאֵלֶּה מִלַּהֲבֵיהֶם. חָשׁ הָאַיִל וְהַחֲזִיר בִּמְהוּמָה וּמְבוּסָה, כִּמְעַט אוֹרִי קָדַר וּמְאוֹר שִׁמְשִׁי כֻּסָּה, תָּמַכְתָּ יַד יְמִינִי בִּימִינִי וַהֲדַסָּה, וְחִצִּים אֲשֶׁר דָּרְכוּ לִי שָׁבוּ בְּלֵב רוֹבֵיהֶם. קָם עָלַי בְּפִשְׁעִי הַנָּבָל הַבַּעַר, גְּרוֹנוֹ עָלַי פָּעַר כַּחֲזִיר בְּתוֹךְ הַיָּעַר, הִקְדַּמְתָּ לִּי מְשִׁיבֵי מִלְחֶמֶת דַּת שָׁעַר, וְהִנְנִי מִשְׁתַּעְשֵׁעַ בְּשִׂכְלָם וּבְנִיבֵיהֶם, וְאַף גַּם זֹאת בִּהְיוֹתָם בְּאֶרֶץ אוֹיבֵיהֶם.\n\nוְאַף גַּם זֹאת בִּהְיוֹתָם בְּאֶרֶץ אֹיְבֵיהֶם לֹא מְאַסְתִּים וְלֹא גְעַלְתִּים לְכַלֹּתָם לְהָפֵר בְּרִיתִי אִתָּם, כִּי אֲנִי יהוה אֱלֹהֵיהֶם: וְזָכַרְתִּי אֶת בְּרִיתִי יַעֲקוֹב, וְאַף אֶת בְּרִיתִי יִצְחָק וְאַף אֶת בְּרִיתִי אַבְרָהָם אֶזְכֹּר, וְהָאָרֶץ אֶזְכֹּר: מִן-הַמֵּצַר קָרָאתִי יָּהּ, עָנָנִי בַמֶּרְחָב יָהּ: יהוה לִי לֹא אִירָא, מַה-יַּעֲשֶׂה לִי אָדָם: יהוה לִי בְּעֹזְרָי, וַאֲנִי אֶרְאֶה בְשֹׂנְאָי: טוֹב לַחֲסוֹת בַּיהוה, מִבְּטֹחַ בָּאָדָם: טוֹב לַחֲסוֹת בַּיהוה, מִבְּטֹחַ בִּנְדִיבִים: כָּל-גּוֹיִם סְבָבוּנִי, בְּשֵׁם יהוה כִּי אֲמִילַם: דַּחֹה דְחִיתַנִי לִנְפֹּל, וַיהוה עֲזָרָנִי:\n\nיהִירִים קָמוּ בְּכָל דּוֹר, וְהָאֱלֹהִים שְׁמָרַנִי, עָלָה אַרְיֵה תְּחִלָּה, בְּכָל פֵּאוֹת זֵרָנִי, קָם אַחֲרָיו דֹּב שַׁכּוּל וְלִמְזַנֵּב מְכָרָנִי, דָּחֹה דְחִיתַנִי לִנְפֹּל וַיהוה עֲזָרָנִי: אָז בְּצֵאתִי מִפֶּרֶךְ, בָּא נָחָשׁ עֲלֵי דֶּרֶךְ, עַל עָיֵף וְיָגֵעַ לְהָבִיא בְלִבּוֹ מֹרֶךְ, גָּדַעְתָּ וְהִכִּיתָ אוֹתוֹ שׁוֹק עַל יָרֶךְ, יוֹם הֵרִים יָד עָנָו עֲלֵיהֶם הִגְבִּירָנִי, דָּחֹה דְחִיתַנִי לִנְפֹּל וַיהוה עֲזָרָנִי: בְּקוּם הָמָן הָאֲגָגִי, כַּתַּנִּין לְבַלְּעֵנִי, וְכָתַב שִׂטְנָה עָלָי, בְּיוֹם אֶחָד לְגַדּעֵנִי, שָׁלַח מִשָּׁמַיִם אֵל וַיּוֹשִׁיעֵנִי, לְמִחְיָה הִשְׁאִירָנִי וְעֹז וְיֶשַׁע אִזְּרָנִי, דָּחֹה דְחִיתַנִי לִנְפֹּל וַיהוה עֲזָרָנִי: שִׁמְךָ מִגְדַּל מִבְטָחִי, אֵל מִבֶּטֶן גּוֹחִי, וְחִלַּצְתָּ אֶת-רוּחִי, מִמָּוֶת וּמִשֶּׁחִי, אֶת-עֵינִי מִן דִּמְעָה, וְאֶת-רַגְלִי מִדֶּחִי, וּבְאֶרֶץ מַדּוּחִי, אֵל אֱלֹהִים הִפְרָנִי, דָּחֹה דְחִיתַנִי לִנְפֹּל וַיהוה עֲזָרָנִי:\n\nדַּחֹה דְחִיתַנִי לִנְפֹּל, וַיהוה עֲזָרָנִי: עָזִּי וְזִמְרָת יָהּ, וַיְהִי-לִי לִישׁוּעָה: קוֹל רִנָּה וִישׁוּעָה בְּאָהֳלֵי צַדִּיקִים, יְמִין יהוה עֹשָׂה חָיִל: יְמִין יהוה רוֹמֵמָה, יְמִין יהוה עֹשָׂה חָיִל: לֹא-אָמוּת כִּי-אֶחְיֶה, וַאֲסַפֵּר מַעֲשֵׂי יָהּ: יַסֹּר יִסְּרַנִּי יָּהּ, וְלַמָּוֶת לֹא נְתָנָנִי: פִּתְחוּ-לִי שַׁעֲרֵי-צֶדֶק, אָבֹא-בָם אוֹדֶה יָהּ: זֶה-הַשַּׁעַר לַיהוה, צַדִּיקִים יָבֹאוּ בוֹ: אוֹדְךָ כִּי עֲנִיתָנִי, וַתְּהִי-לִי לִישׁוּעָה: לוּלֵי יהוה שֶׁהָיָה לָנוּ, יֹאמַר-נָא יִשְׂרָאֵל:\n\nאֵיךְ זָרִים, אַכְזָרִים, כַּדְּבוֹרִים סְבָבוּנוּ, בְּקוּם הָמָן, בְּזֶה הַזְּמָן, כְּשֹׁד שַׁלְמָן שְׁדָדוּנוּ. בְּרֹב מַעַל, סַף רַעַל, בְּלִי תַעַל הִשְׁקוּנוּ. לוּלֵי יהוה שֶׁהָיָה לָנוּ, אֲזַי חַיִּים בְּלָעוּנוּ. אֵיךְ דִּמּוּ, וזָמְמוּ, בְּלִבָּם נִינָם יַחַד. בְּמַחֲשָׁבַת, לְהַחֲרִיב בַּת, יִשְׂרָאֵל גּוֹי אֶחָד. בְּסוֹד סוֹדָם, לְהַשְׁמִידָם, לְהַכְחִידָם, כְּמוֹ כַחַד. וּבֵין תַּנּוּר וְכִירַיִם, הַמַּיִם שְׁטָפוּנוּ. לוּלֵי יהוה שֶׁהָיָה לָנוּ, אֲזַי חַיִּים בְּלָעוּנוּ. קָם צוֹרֵר, וְלִי עוֹרֵר, אֵיבָתוֹ וְשִׂנְאָתוֹ. וְדָת הֶעֱמִיד, וְקֵץ לַשְׁמִיד, עֲדַת שַׁדַּי וְנַחֲלָתוֹ. וְצוּר חָמַל, וְטוֹב גָּמַל, וְהֶרְאָה אֶת-גְּבוּרָתוֹ. לְהַאֲבִידוֹ, לְהַכְחִידוֹ, וּבָנָיו אֲשֶׁר עִנּוּנוּ. חָשַׁב צָר, בְּעֵת מֵצָר, וְהִפִּיל פּוּר גּוֹרָלוֹ. וְצוּר הִקְשִׁיב, וְאָז הֵשִׁיב, בְּרֹאשׁוֹ אֶת תַּגְמוּלוֹ. וְאֵל נֶאְדָּר, בְּחֹדֶשׁ אֲדָר, עֹז הֶרְאָה לִקְהָלוֹ. בְּמוֹ רֶצַח, עֲדֵי נֶצַח, הִכָּה אֲשֶׁר הִכּוּנוּ. לוּלֵי יהוה שֶׁהָיָה לָנוּ, אֲזַי חַיִּים בּלָעוּנוּ.\n\nלוּלֵי יהוה שֶׁהָיָה לָנוּ, יֹאמַר-נָא יִשְׂרָאֵל: לוּלֵי יהוה שֶׁהָיָה לָנוּ, בְּקוּם עָלֵינוּ אָדָם: אֲזַי חַיִּים בְּלָעוּנוּ, בַּחֲרוֹת אַפָּם בָּנוּ: אֲזַי הַמַּיִם שְׁטָפוּנוּ, נַחְלָה עָבַר עַל-נַפְשֵׁנוּ: אֲזַי עָבַר עַל-נַפְשֵׁנוּ, הַמַּיִם הַזֵּידוֹנִים: בָּרוּךְ יהוה, שֶׁלֹּא נְתָנָנוּ טֶרֶף לְשִׁנֵּיהֶם: נַפְשֵׁנוּ כְּצִפּוֹר נִמְלְטָה מִפַּח יוֹקְשִׁים, הַפַּח נִשְׁבָּר וַאֲנַחְנוּ נִמְלָטְנוּ: עֶזְרֵנוּ בְּשֵׁם יהוה, עֹשֵׂה שָׁמַיִם וָאָרֶץ:\n\n אֲדֹנָי שְׁמָעָה, אֲדֹנָי סְלָחָה, אֲדֹנָי הַקֲשִׁיבָה וַעֲשֵׂה אַל תְּאַחַר, לְמַעֲנְךָ אֱלֹהַי, כִּי שִׁמְךָ נִקְרָא עַל עִירְךָ וְעַל עַמֶּךָ: הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם:","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, וּמִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לַחַטָּאִים, וּסְלִיחָה לַפּוֹשְׁעִים. עוֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וְרוּחַ, לֹא כְרָעָתָם לָהֶם גּוֹמֵל. אֵל, הוֹרֵתָנוּ לוֹמַר מִדּוֹת שְׁלֹשׁ עֶשְׂרֵה, זְכֹר לָנוּ הַיּוֹם בְּרִית שְׁלֹשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָו מִקֶּדֶם, וְכֵן כָּתוּב בְּתוֹרָתָךְ: וַיֵּרֶד יהוה בֶּעָנָן וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם יהוה: וְשָׁם נֶאֱמַר:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"אַנְשֵׁי אֱמוּנָה אָבָדוּ, בָּאִים בְּכֹחַ מַעֲשֵׂיהֶם. גִּבּוֹרִים לַעֲמֹד בַּפֶּרֶץ, דּוֹחִים אֶת-הַגְּזֵרוֹת. הָיוּ לָנוּ לְחוֹמָה, וּלְמַחְסֶה בְּיוֹם זָעַם. זוֹעֲכִים אַף בְּלַחֲשָׁם, חֵמָה עָצרוּ בְּשַׁוְּעָם. טֶרֶם קְרָאוּךָ עֲנִיתָם, יוֹדְעִים לַעֲתֹר וּלְרַצּוֹת. כְּאָב רִחַמְתָּ לְמַעֲנָם, לֹא הֱשִׁיבוֹתָ פְנֵיהֶם רֵיקָם. מֵרֹב עֲוׂנֵינוּ אֲבַדְנוּם, נֶאֶסְפוּ מֶנּוּ בַּחֲטָאֵינוּ. סָעוּ הֵמָּה לִמְנוּחוֹת, עָזבוּ אוֹתָנוּ לַאֲנָחוֹת. פַּסּוּ גוֹדְרֵי גָדֵר, צֻמְּתוּ מְשִׁיבֵי חֵמָה. קָמִים בַּפֶּרֶץ אַיִן, רְאוּיִים לְרַצּוֹתְךָ אָפֵסוּ. שׁוֹטַטְנוּ בְּאַרְבַּע פִּנּוֹת, תְּרוּפָה לֹא מָצָאנוּ. שַׁבְנוּ אֵלֶיךָ בּבֹשֶׁת פָּנֵינוּ, לשַׁחֲרָךְ אֵל בְּעֵת צָרוֹתֵינוּ.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, וּמִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לַחַטָּאִים, וּסְלִיחָה לַפּוֹשְׁעִים. עוֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וְרוּחַ, לֹא כְרָעָתָם לָהֶם גּוֹמֵל. אֵל, הוֹרֵתָנוּ לוֹמַר מִדּוֹת שְׁלֹשׁ עֶשְׂרֵה, זְכֹר לָנוּ הַיּוֹם בְּרִית שְׁלֹשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָו מִקֶּדֶם, וְכֵן כָּתוּב בְּתוֹרָתָךְ: וַיֵּרֶד יהוה בֶּעָנָן וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם יהוה: וְשָׁם נֶאֱמַר:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"תָּמַהְנוּ מֵרָעוֹת, תָּשַׁשׁ כֹּחֵנוּ מִצָּרוֹת. שַׁחְנוּ עַד לִמְאֹד, שָׁפַלְנוּ עַד עָפָר. רַחוּם כָּךְ הִיא מִדָּתֵנוּ, קְשֵׁי עֹרֶף וּמַמְרִים אֲנַחְנוּ. צָעַקְנוּ בְּפִינוּ חָטָאנוּ, פְּתַלְתּוֹל וְעִקֵּשׁ לִבֵּנוּ. עֶלְיוֹן, רַחֲמֶיךָ מֵעוֹלָם, סְלִיחָה עִמְּךָ הִיא. נִחָם עַל הָרָעָה, מַטֵּה כְלַפֵּי חֶסֶד. לֹא תִתְעַלַּם בְּעִתּוֹת כָּאֵל, כִּי בְצָרָה גְדוֹלָה אֲנָחְנוּ. יִוָּדַע לְעֵינֵי הַכֹּל, טוּבְךָ וְחַסְדְּךָ עִמָּנוּ. חֲתֹם פִּי-שָׂטָן, וְאַל יַשְׂטִין עָלֵינוּ, זְעֹם בּוֹ ויִדֹּם. וְיַעֲמֹד מֵלִיץ טוֹב לְצַדְּקֵנוּ, הוּא יַגִּיד יָשְׁרֵנוּ. דְּרָכֶיךָ רַחוּם וְחַנּוּן גִּלִּיתָ לְנֶאֱמַן בָּיִת. בְּבַקְשׁוֹ אָז מִלּפָנֶיךָ, אֱמוּנָתךָ הוֹדַעְתָּ לּוֹ.","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, וּמִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לַחַטָּאִים, וּסְלִיחָה לַפּוֹשְׁעִים. עוֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וְרוּחַ, לֹא כְרָעָתָם לָהֶם גּוֹמֵל. אֵל, הוֹרֵתָנוּ לוֹמַר מִדּוֹת שְׁלֹשׁ עֶשְׂרֵה, זְכֹר לָנוּ הַיּוֹם בְּרִית שְׁלֹשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָו מִקֶּדֶם, וְכֵן כָּתוּב בְּתוֹרָתָךְ: וַיֵּרֶד יהוה בֶּעָנָן וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם יהוה: וְשָׁם נֶאֱמַר:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב-חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה.\nוְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ:\nסְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחַל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"וּכְשֶׁחָטאוּ יִשְׂרָאֵל בַּמִּדְבָּר, עָמַד מֹשֶׁה בִּתְפִלָּה לְפָנֶיךָ, וּבִקֵּשׁ רַחֲמִים עַל עַמְּךָ יִשְׂרָאֵל וְכָךְ אָמַר בִּתְפִלָּתוֹ: סְלַח-נָא לַעֲוׂן הָעָם הַזֶּה כְּגֹדֶל חַסְדֶּךָ, וְכַאֲשֶׁר נָשָׂאתָה לָעָם הַזֶּה מִמִּצְרַיִם וְעַד-הֵנָּה: אַף אַתָּה הֱשִׁיבוֹתָ לוֹ כְּדַרְכֵי טוּבְךָ בִּשַּׂרְתּוֹ וַחֲנַנְתּוֹ וְאָמַרְתָּ לוֹ: סָלַחְתִּי כִּדְבָרֶךָ:\n\nדָּנִיֵּאל אִישׁ חֲמוּדוֹת אָמַר לְפָנֶיךָ: הַטֵּה אֱלֹהַי אָזְנְךָ וּשֲׁמָע, פְּקַח עֵינֶיךָ וּרְאֵה שֹׁמְמֹתֵינוּ וְהָעִיר אֲשֶׁר-נִקְרָא שִׁמְךָ עָלֶיהָ, כִּי לֹא עַל-צִדְקֹתֵינוּ אֲנַחְנוּ מַפִּילִים תַּחֲנוּנֵינוּ לְפָנֶיךָ, כִּי עַל-רַחֲמֶיךָ הָרַבִּים: אֲדֹנָי שְׁמָעָה, אֲדֹנָי סְלָחָה, אֲדֹנָי הַקְשִׁיבָה וַעֲשֵׂה אַל-תְּאַחַר, לְמַעֲנְךָ אֱלֹהַי כִּי-שִׁמְךָ נִקְרָא עַל-עִירְךָ וְעַל עַמֶּךָ: וְלִירוּשָׁלַיִם עִירָךְ אָמַרְתָּ לָהּ: הִנְנִי נִשְׁפָּט אוֹתָךְ עַל-אָמְרֵךְ לֹא חָטָאתִי: אֲנַחְנוּ בּוֹשְׁנוּ בְּמַעֲשֵׂינוּ וְנִכְלַמְנוּ בַּעֲוׂנוֹתֵינוּ, אֵין לָנוּ פֶּה לְהָשִׁיב וְלֹא מֵצַח לְהָרִים רֹאשׁ.\n\nאֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אַל תַּעַשׂ עִמָּנוּ כָּלָה, תֹּאחֵז יָדְךָ בַּמִּשְׁפָּט. בְּבֹא תוֹכֵחָה נֶגְדֶּךָ, שְׁמֵנוּ מִסִּפְרְךָ אַל תֶּמַח. גִּשְׁתְּךָ לַחֲקֹר מוּסָר, רַחֲמֶיךָ יְקַדְּמוּ רָגְזֶךָ. דַּלּוּת מַעֲשִׂים בְּשׁוּרֶךָ, קָרֵב צֶדֶק מֵאֵלֶיךָ. הוֹרֵנוּ, בְּזַעֲקֵנוּ לָךְ, צַו יְשׁוּעָתֵנוּ בְּמַפְגִּיעַ. וְתָשִׁיב שְׁבוּת אָהֳלֵי תָם, פְּתָחָיו רְאֵה כִּי שָׁמֵמוּ. זְכֹר נָאַמְתָּ, עֵדוּת לֹא תִשָּׁכַח מִפִּי זַרְעוֹ. חוֹתַם תְּעוּדָה תַּתִּיר, סוֹדְךָ שִׂים בְּלִמּוּדֶיךָ. טַבּוּר אַגַּן הַסַּהַר, נָא אַל יֶחְסַר הַמָּזֶג. יָהּ, דַּע אֶת-יִשְׂרָאֵל אֲשֶׁר יְדָעוּךָ, מַגֵּר אֶת-הַגּוֹיִם אֲשֶׁר לֹא יְדָעוּךָ. כִּי תָשִׁיב לְבִצָּרוֹן, לְכוּדִים אֲסִירֵי הַתִּקְוָה.\n\nאָשַׁמְנוּ מִכָּל-עָם, בֹּשְׁנוּ מִכָּל-גּוֹי. גָּלָה מִמֶּנּוּ מָשׂוֹשׂ, דָּוֶה לִבֵּנוּ בַּחֲטָאֵינוּ. הָחְבַּל אֶוְיֵינוּ, וְנִפְרָע פְּאֵרֵנוּ. זְבוּל מִקְדָּשֵׁנוּ, חָרֵב בַּעֲוֹנֵינוּ. טִירָתֵנוּ הָיְתָה לְשַׁמָּה, יְפִי אַדְמָתֵנוּ לְזָרִים, כֹּחֵנוּ לְנָכְרִים. לְעֵינֵינוּ עָשְׁקוּ עֲמָלֵנוּ, מְמֻשָּׁךְ וּמוֹרָט מִמֶּנּוּ. נָתְנוּ עֻלָּם עָלֵינוּ, סָבַלְנוּ עַל שִׁכְמֵנוּ. עֲבָדִים מָשְׁלוּ בָנוּ, פּוֹרֵק אֵין מִיָּדָם. צָרוֹת רַבּוֹת סְבָבוּנוּ, קְרָאנוּךָ יהוה אֱלֹהֵינוּ. רָחַקְתָּ מִמֶּנּוּ בַּעֲוׂנֵינוּ, שַׁבְנוּ מֵאַחֲרֶיךָ, תָּעִינוּ כַּצֹּאן וְאָבָדְנוּ. וַעֲדַיִן לֹא שַׁבְנוּ מִתְּעִיָּתֵנוּ, וְהֵיאַךְ נָעִיז פָּנֵינוּ, וְנַקְשֶׁה עָרְפֵּנוּ, לוֹמַר לְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ צַדִּיקִים אֲנַחְנוּ וְלֹא-חָטָאנוּ.\n\nעֶזְרָא הַסּוֹפֵר אָמַר לְפָנֶיךָ: אֱלֹהַי, בֹּשְׁתִּי וְנִכְלַמְתִּי לְהָרִים אֱלֹהַי פָּנַי אֵלֶיךָ, כִּי עֲוׂנֹתֵינוּ רָבוּ לְמַעְלָה רֹאשׁ, וְאַשְׁמָתֵנוּ גָדְלָה עַד לַשָּׁמָיִם: וְאַתָּה אֱלוֹהַּ סְלִיחוֹת, חַנּוּן ורַחוּם, אֶרֶךְ-אַפַּיִם וְרַב-חֶסֶד, וְלֹא עֲזַבְתָּם. אַל תַּעַזְבֵנוּ אָבִינוּ, אַל תִּטְּשֵׁנוּ מַלְכֵּנוּ, וְאַל תִּשְׁכָּחֵנוּ יוֹצְרֵנוּ, וְאַל תַּעַשׂ עִמָּנוּ כָלָה בְּגָלוּתֵנוּ, וְקַיֵּם לָנוּ יהוה אֱלֹהֵינוּ אֶת-הַדָּבָר שֶׁהִבְטַחְתָּנוּ, עַל יְדֵי יִרְמְיָה חוֹזָךְ, כָּאָמוּר: בַּיָּמִים הָהֵם וּבָעֵת הַהִיא, נְאֻם-יהוה, יבֻקַּשׁ אֶת-עֲוׂן יִשְׂרָאֵל וְאֵינֶנּוּ, וְאֶת-חַטֹּאת יְהוּדָה וְלֹא תִמָּצֶאנָה, כִּי אֶסְלַח לַאֲשֶׁר אַשְׁאִיר: וְאַל יעַכֵּב לפָנֶיךָ כָּל-חֵטְא וְעוׂן אֶת תְּפִלָּתֵנוּ, וּמְחוֹל וּסְלַח לְכָל-עֲוׂנוֹתֵינוּ, כִּי אֵל טוֹב וסַלָּח אָתָּה.\n\nמַה-נֹּאמַר לְפָנֶיךָ יוֹשֵׁב מָרוֹם, וּמַה נְּסַפֵּר לְפָנֶיךָ שׁוֹכֵן שְׁחָקִים, הֲלֹא הַנִּסְתָּרוֹת והַנִּגְלוֹת אַתָּה יוֹדֵעַ, אַתָּה יוֹדֵעַ רָזֵי עוֹלָם, וְתַעֲלוּמוֹת סִתְרֵי כָל-חָי, אַתָּה חוֹפֵשׂ כָּל-חַדְרֵי בָטֶן, רֹאֶה כלָיוֹת וָלֵב. אֵין דָּבָר נֶעְלָם מִמָּךְ, וְאֵין נִסְתָּר מִנֶּגֶד עֵינֶיךָ.\n\nיְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּמְחֹל לָנוּ אֶת-כָּל-חַטֹּאתֵינוּ, וּתְכַפֵּר לָנוּ אֶת-כָּל-עֲוׂנוֹתֵינוּ, וְתִמְחֹל וְתִסְלַח לכָל-פְּשָׁעֵינוּ, וְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ: סְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחֹל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי, טוֹב וְסַלָּח, וְרַב-חֶסֶד לְכָל-קֹרְאֶיךָ: לְמַעַן-שִׁמְךָ יהוה, וְסָלַחְתָּ לַעֲוׂנִי כִּי רַב-הוּא: לְמַעַן-שִׁמְךָ יהוה תְּחַיֵּנִי, בְּצִדְקָתְךָ תוֹצִיא מִצָּרָה נַפְשִׁי: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב-לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה: יהוה צְבָאוֹת, אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם-קָרְאֵנוּ: הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם:","cond":["shacharitTachanun","ester"]},{"kind":"text","text":"וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית, וְהִרְבָּה לְהָשִׁיב אַפּוֹ וְלֹא יָעִיר כָּל חֲמָתוֹ: אַתָּה יהוה, לֹא תִכְלָא רַחֲמֶיךָ מִמֶּנִּי, חַסְדְּךָ וַאֲמִתְּךָ תָּמִיד יִצְּרוּנִי: הוֹשִׁיעֵנוּ יהוה אֱלֹהֵינוּ וְקַבְּצֵנוּ מִן הַגּוֹיִם, לְהֹדוֹת לְשֵׁם קָדְשֶׁךָ, לְהִשְׁתַּבֵּחַ בִּתְהִלָּתֶךָ: אִם עֲוׂנוֹת תִּשְמָר יָהּ, אֲדֹנָי, מִי יַעֲמֹד: כִּי עִמְּךָ הַסְּלִיחָה, לְמַעַן תִּוָּרֵא: לֹא כַחֲטָאֵינוּ עָשָׂה לָנוּ, וְלֹא כַעֲוׂנֹתֵינוּ גָמַל עָלֵינוּ. אִם עֲוׂנֵינוּ עָנוּ בָנוּ, יהוה, עֲשֵׂה לְמַעַן שְׁמֶךָ. זְכֹר רַחֲמֶיךָ יהוה וַחֲסָדֶיךָ, כִּי מֵעוֹלָם הֵמָּה: יַעַנְךָ יהוה בְּיוֹם צָרָה, יְשַׂגֶּבְךָ שֵׁם אֱלֹהֵי יַעֲקֹב: יהוה הושִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ: אָבִינוּ מַלְכֵּנוּ, חָנֵּנוּ וַעֲנֵנוּ, כִּי אֵין בָּנוּ מַעֲשִׂים. עֲשֵׂה עִמָּנוּ צְדָקָה כְּרֹב רַחֲמֶיךָ, וְהוֹשִׁיעֵנוּ לְמַעַן שְׁמֶךָ.\n\nוְעַתָּה אֲדֹנָי אֱלֹהֵינוּ אֲשֶׁר הוֹצֵאתָ אֶת עַמְּךָ מֵאֶרֶץ מִצְרַיִם בְּיָד חֲזָקָה, וַתַּעַשׂ לְךָ שֵׁם כַּיּוֹם הַזֶּה, חָטָאנוּ רָשָׁעְנוּ: אֲדֹנָי, כְּכָל צִדְקֹתֶךָ יָשָׁב נָא אַפְּךָ וַחֲמָתְךָ מֵעִירְךָ יְרוּשָׁלַיִם הַר קָדְשֶׁךָ, כִּי בַחֲטָאֵינוּ וּבַעֲוׂנוֹת אֲבֹתֵינוּ, יְרוּשָׁלִַם וְעַמְּךָ לְחֶרְפָּה לְכָל סְבִיבֹתֵינוּ: וְעַתָּה שְׁמַע אֱלֹהֵינוּ אֶל תְּפִלַּת עַבְדְּךָ וְאֶל תַּחֲנוּנָיו, וְהָאֵר פָּנֶיךָ עַל מִקְדָּשְׁךָ הַשָּׁמֵם, לְמַעַן אֲדֹנָי: הַטֵּה אֱלֹהַי אָזְנְךָ וּשְׁמָע, פְּקַח עֵינֶיךָ וּרְאֵה שֹׁמְמֹתֵינוּ וְהָעִיר אֲשֶׁר נִקְרָא שִׁמְךָ עָלֶיהָ, כִּי לֹא עַל צִדְקֹתֵינוּ אֲנַחְנוּ מַפִּילִים תַּחֲנוּנֵינוּ לְפָנֶיךָ, כִּי עַל רַחֲמֶיךָ הָרַבִּים: אֲדֹנָי שְׁמָעָה, אֲדֹנָי סְלָחָה, אֲדֹנָי הַקֲשִׁיבָה וַעֲשֵׂה אַל תְּאַחַר, לְמַעֲנְךָ אֱלֹהַי, כִּי שִׁמְךָ נִקְרָא עַל עִירְךָ וְעַל עַמֶּךָ:\n\nאָבִינוּ אָב הָרַחֲמָן, הַרְאֵנוּ אוֹת לְטוֹבָה וְקַבֵּץ נְפוּצוֹתֵינוּ מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ. יַכִּירוּ וְיֵדְעוּ כָּל הַגּוֹיִם, כִּי אַתָּה יהוה אָבִינוּ אָתָּה, אֲנַחְנוּ הַחֹמֶר וְאַתָּה יֹצְרֵנוּ וּמַעֲשֵׂה יָדְךָ כֻּלָּנוּ: אָבִינוּ מַלְכֵּנוּ, צוּרֵנוּ מַלְכֵּנוּ וְגוֹאֲלֵנוּ, חוּסָה יהוה עַל עַמֶּךָ וְאַל תִּתֵּן נַחֲלָתְךָ לְחֶרְפָּה לִמְשָׁל בָּם גּוֹיִם, לָמָּה יֹאמְרוּ בָעַמִּים אַיֵּה אֱלֹהֵיהֶם: יָדַעְנוּ יהוה כִּי חָטָאנוּ וְאֵין מִי יַעֲמֹד בַּעֲדֵנוּ, אֶלָּא שִׁמְךָ הַגָּדוֹל יַעֲמָד לָנוּ בְּעֵת צָרָה. וּכְרַחֵם אָב עַל בָּנִים רַחֵם עָלֵינוּ. חֲמֹל עַל עַמָּךְ וְרַחֵם עַל נַחֲלָתָךְ, חוּסָה נָּא כְּרֹב רַחֲמֶיךָ, חָנֵנוּ מַלְכֵּנוּ וַעֲנֵנוּ. לְךָ יהוה הַצְּדָקָה, עֹשֵׂה נִפְלָאוֹת בְּכָל עֵת וָעֵת. הַבֵּט נָא וְהוֹשִׁיעָה נָּא צֹאן מַרְעִיתֶךָ. אַל יִמְשָׁל בָּנוּ קֶצֶף, כִּי לְךָ יהוה הַיְשׁוּעָה, בְּךָ תוֹחַלְתֵּנוּ. אֱלוֹהַּ סְלִיחוֹת, אָנָּא סְלַח נָא. כִּי אֵל טוֹב וְסַלָּח אָתָּה. אָנָּא מֶלֶךְ רַחוּם וְחַנּוּן, זְכֹר וְהַבֵּט לִבְרִית בֵּין הַבְּתָרִים, וְתֵרָאֶה לְפָנֶיךָ עֲקֵדַת יָחִיד. וּלְמַעַן יִשרָאֵל אָבִינוּ, אַל תַּעַזְבִנוּ אָבִינוּ וְאַל תִּטְּשֵנוּ מַלְכֵּנוּ, וְאַל תִּשְׁכָּחֵנוּ יוֹצְרֵנוּ, וְאַל תַּעַשׂ עִמָּנוּ כָלָה בְּגָלוּתֵנוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.\n\nאֵין כָּמוֹך חַנּוּן וְרַחוּם, אֱלֹהֵינוּ, אֵין כָּמוֹךָ אֵל אֶרֶך אַפַּיִם וְרַב חֶסֶד וֶאֱמֶת. הוֹשִׁיעֵנוּ וְרַחֲמֵנוּ, מֵרַעַשׁ וּמֵרֹגֶז הַצִּילֵנוּ. זְכֹר לַעֲבָדֶיך לְאַבְרָהָם לְיִצְחָק וּלְיַעֲקֹב, אַל תֵּפֶן אֶל קְשִׁי הָעָם הַזֶּה וְאֶל רִשְׁעוֹ וְאֶל חַטָּאתוֹ: שׁוּב מֵחָרוֹן אַפֶּךָ, וְהִנָּחֵם עַל הָרָעָה לְעַמֶּךָ: וְהָסֵר מִמֶּנּוּ מַכַּת הַמָּוֶת כִּי רַחוּם אָתָּה, כִּי כֵן דַּרְכְּךָ לַעֲשׂוֹת חֶסֶד חִנָּם בְּכָל דוֹר וָדוֹר. אָנָּא יהוה הוֹשִׁיעָה נָּא, אָנָּא יהוה הַצְלִיחָה נָּא: אָנָּא יהוה עֲנֵנוּ בְיוֹם קָרְאֵנוּ. לְךָ יהוה קִוִּינוּ, לְךָ יהוה חִכִּינוּ, לְךָ יהוה נְיַחֵל, אַל תֶּחֱשֶׁה וּתְעַנֵּנוּ, כִּי נַאֲמוּ גוֹיִם: אָבְדָה תִקְוָתָם. כָּל בֶּרֶך לְךָ תִּכְרַע, וְכָל קוֹמָה לְפָנֶיךָ תִּשְׁתַּחֲוֶה.\n\nהַפּוֹתֵחַ יָד בִּתְשׁוּבַה לְקַבֵּל פּוֹשְׁעִים וְחַטָּאִים, נִבְהֲלָה נַפְשֵׁנוּ מֵרֹב עִצְּבוֹנֵנוּ. אַל תִּשְׁכָּחֵנוּ נֶצַח, קוּמָה וְהוֹשִׁיעֵנוּ. אַל תִּשְׁפֹּך חֲרוֹנְךָ עָלֵינוּ, כִּי עַמְּךָ אֲנַחְנוּ בְּנֵי בְרִיתֶךָ. אֵל, הַבִּיטָה, דַּל כְּבוֹדֵנוּ בַּגּוֹיִם וְשִׁקְּצוּנוּ כְּטֻמְאַת הַנִּדָּה. עַד מַתָּי עֻזְּךָ בַשְּׁבִי, וְתִפְאַרְתְּךָ בְיַד צָר? הֵמָה יִרְאוּ וְיֵבֹשׁוּ וְיֵחַתּוּ מִגְּבוּרָתָם. עוֹרְרָה גְבוּרָתֶךָ, וְהוֹשִׁיעֵנוּ לְמַעַן שְׁמֶךָ. אַל יִמְעֲטוּ לְפָנֶיךָ תְּלָאוֹתֵינוּ, מַהֵר יְקַדְּמוּנוּ רַחֲמֶיךָ בְּעֵת צָרוֹתֵינוּ. לֹא לְמַעֲנֵנוּ, אֶלָּא לְמַעַנְךָ פְעֹל, וְאַל תַּשְׁחִית אֶת זֵכֶר שְׁאֵרִיתֵנוּ, כִּי לְךָ מְיַחֲלוֹת עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה. וּזְכֹר לָנוּ עֵדוּתֵנוּ בְכָל יוֹם תָּמִיד אוֹמְרִים פַּעֲמַיִם בְּאַהֲבָה: \"שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:\"","cond":["shacharitTachanun","ester"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","monThu"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, וּמִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לַחַטָּאִים, וּסְלִיחָה לַפּוֹשְׁעִים. עוֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וְרוּחַ, לֹא כְרָעָתָם לָהֶם גּוֹמֵל. אֵל, הוֹרֵתָנוּ לוֹמַר מִדּוֹת שְׁלֹשׁ עֶשְׂרֵה, זְכֹר לָנוּ הַיּוֹם בְּרִית שְׁלֹשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָו מִקֶּדֶם, וְכֵן כָּתוּב בְּתוֹרָתָךְ: וַיֵּרֶד יהוה בֶּעָנָן וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם יהוה: וְשָׁם נֶאֱמַר:\nוַיַעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, (א) אֵל (ב) רַחוּם (ג) וְחַנּוּן, (ד) אֶרֶך (ה) אַפַּיִם, (ו) וְרַב חֶסֶד (ז) וֶאֱמֶת: (ח) נֹצֵר חֶסֶד (ט) לָאֲלָפִים, (י) נֹשֵׂא עָוׂן (יא) וָפֶשַׁע (יב) וְחַטָּאָה, (יג) וְנַקֵּה.\n\nאַנְשֵׁי אֱמוּנָה אָבָדוּ, בָּאִים בְּכֹחַ מַעֲשֵׂיהֶם. גִּבּורִים לַעֲמוֹד בַּפֶּרֶץ, דּוֹחִים אֶת הַגְּזֵרוֹת. הָיוּ לָנוּ לְחוֹמָה, וּלְמַחְסֶה בְּיוֹם זַעַם. זוֹעֲכִים אַף בְּלַחֲשָׁם, חֵמָה עָצְרוּ בְּשַׁוְּעָם. טֶרֶם קְרָאוּךָ עֲנִיתָם, יוֹדְעִים לַעֲתוֹר וּלְרַצּוֹת. כְּאָב רִחַמְתָּ לְמַעֲנָם, לא הֱשִׁיבוֹתָ פְנֵיהֶם רֵיקָם. מֵרֹב עֲוׂנֵינוּ אֲבַדְנוּם, נֶאֶסְפוּ מֶנּוּ בַּחֲטָאֵינוּ. סָעוּ הֵמָּה לִמְנוּחוֹת, עָזְבוּ אוֹתָנוּ לַאֲנָחוֹת. פַּסּוּ גוֹדְרֵי גָדֵר, צֻמְּתוּ מְשִׁיבֵי חֵמָה. קָמִים בַּפֶּרֶץ אַיִן, רְאוּיִים לְרַצּוֹתְךָ אָפֵסוּ. שׁוֹטַטְנוּ בְאַרְבַּע פִּנּוֹת, תְּרוּפָה לֹא מָצָאנוּ. שַׁבְנוּ אֵלֶיךָ בְּבֹשֶׁת פָּנֵינוּ, לְשַׁחֲרָךְ אֵל בְּעֵת צָרוֹתֵינוּ.","cond":["shacharitTachanun","monThu"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","monThu"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, וּמִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לַחַטָּאִים, וּסְלִיחָה לַפּוֹשְׁעִים. עוֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וְרוּחַ, לֹא כְרָעָתָם לָהֶם גּוֹמֵל. אֵל, הוֹרֵתָנוּ לוֹמַר מִדּוֹת שְׁלֹשׁ עֶשְׂרֵה, זְכֹר לָנוּ הַיּוֹם בְּרִית שְׁלֹשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָו מִקֶּדֶם, וְכֵן כָּתוּב בְּתוֹרָתָךְ: וַיֵּרֶד יהוה בֶּעָנָן וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם יהוה: וְשָׁם נֶאֱמַר:\nוַיַעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, (א) אֵל (ב) רַחוּם (ג) וְחַנּוּן, (ד) אֶרֶך (ה) אַפַּיִם, (ו) וְרַב חֶסֶד (ז) וֶאֱמֶת: (ח) נֹצֵר חֶסֶד (ט) לָאֲלָפִים, (י) נֹשֵׂא עָוׂן (יא) וָפֶשַׁע (יב) וְחַטָּאָה, (יג) וְנַקֵּה.\n\nתָּמַהְנוּ מֵרָעוֹת, תָּשַׁשׁ כֹּחֵנוּ מִצָּרוֹת. שַׁחְנוּ עַד לִמְאֹד, שָׁפַלְנוּ עַד עָפָר. רַחוּם, כַּךְ הִיא מִדָּתֵנוּ, קְשֵׁי עֹרֶף וּמַמְרִים אֲנַחְנוּ. צָעַקְנוּ בְּפִינוּ חָטָאנוּ, פְּתַלְתּוֹל וְעִקֵּשׁ לִבֵּנוּ. עֶלְיוֹן, רַחֲמֶיךָ מֵעוֹלָם, סְלִיחָה עִמְּךָ הִיא. נִחָם עַל הָרָעָה, מַטֵּה כְלַפֵּי חֶסֶד. לֹא תִתְעַלָּם בְּעִתּוֹת כָּאֵל, כִּי בְצָרָה גְדוֹלָה אֲנַחְנוּ. יִוָּדַע לְעֵינֵי הַכֹּל, טוּבְךָ וְחַסְדְּךָ עִמָּנוּ. חֲתֹם פֶּה שָׂטָן וְאַל יַשְׂטִין עָלֵינוּ, זְעֹם בּוֹ וְיִדֹּם. וְיַעֲמֹד מֵלִיץ טוֹב לְצַדְּקֵנוּ, הוּא יַגִּיד יָשְׁרֵנוּ. דְּרָכֶיךָ רַחוּם וְחַנּוּן גִּלִּיתָ לְנֶאֱמַן בַּיִת. בְּבַקְשׁוֹ אָז מִלְּפָנֶיךָ, אֱמוּנָתְךָ הוֹדַעְתָּ לּוֹ.","cond":["shacharitTachanun","monThu"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["shacharitTachanun","monThu"]},{"kind":"text","text":"אֵל מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא רַחֲמִים, וּמִתְנַהֵג בַּחֲסִידוּת. מוֹחֵל עֲוׂנוֹת עַמּוֹ, מַעֲבִיר רִאשׁוֹן רִאשׁוֹן. מַרְבֶּה מְחִילָה לַחַטָּאִים, וּסְלִיחָה לַפּוֹשְׁעִים. עוֹשֵׂה צְדָקוֹת עִם כָּל בָּשָׂר וְרוּחַ, לֹא כְרָעָתָם לָהֶם גּוֹמֵל. אֵל, הוֹרֵתָנוּ לוֹמַר מִדּוֹת שְׁלֹשׁ עֶשְׂרֵה, זְכֹר לָנוּ הַיּוֹם בְּרִית שְׁלֹשׁ עֶשְׂרֵה, כְּמוֹ שֶׁהוֹדַעְתָּ לֶעָנָו מִקֶּדֶם, וְכֵן כָּתוּב בְּתוֹרָתָךְ: וַיֵּרֶד יהוה בֶּעָנָן וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם יהוה: וְשָׁם נֶאֱמַר:\nוַיַעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, (א) אֵל (ב) רַחוּם (ג) וְחַנּוּן, (ד) אֶרֶך (ה) אַפַּיִם, (ו) וְרַב חֶסֶד (ז) וֶאֱמֶת: (ח) נֹצֵר חֶסֶד (ט) לָאֲלָפִים, (י) נֹשֵׂא עָוׂן (יא) וָפֶשַׁע (יב) וְחַטָּאָה, (יג) וְנַקֵּה.\n\nאֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אַל תַּעַשׂ עִמָּנוּ כָּלָה, תֹּאחֵז יָדְךָ בַּמִּשְׁפָּט. בְּבוֹא תוֹכֵחָה נֶגְדֶּךָ, שְׁמֵנוּ מִסִּפְרְךָ אַל תֶּמַח. גִּשְׁתְּךָ לַחֲקֹר מוּסָר, רַחֲמֶיךָ יְקַדְּמוּ רָגְזֶךָ. דַּלּוּת מַעֲשִׂים בְּשׁוּרֶךָ, קָרֵב צֶדֶק מֵאֵלֶיךָ. הורֵנוּ, בְּזַעֲקֵנוּ לָךְ, צַו יְשׁוּעָתֵנוּ בְּמַפְגִּיעַ. וְתָשִׁיב שְׁבוּת אָהֳלֵי תָם, פְּתָחָיו רְאֵה כִּי שָׁמֵמוּ. זְכוֹר נָאַמְתָּ, עֵדוּת לֹא תִשָּׁכַח מִפִּי זַרְעוֹ. חוֹתַם תְּעוּדָה תַתִּיר, סוֹדְךָ שִׂים בְּלִמּוּדֶךָ. טַבּוּר אַגַּן הַסַּהַר, נָא אַל יֶחְסַר הַמָּזֶג. יָהּ, דַּע אֶת יִשְׂרָאֵל אֲשֶׁר יְדָעוּךָ, מַגֵּר אֶת הַגּוֹיִם אֲשֶׁר לֹא יְדָעוּךָ. כִּי תָשִׁיב לְבִצָּרון, לְכוּדִים אֲסִירֵי הַתִּקְוָה.\n\nמַה נֹּאמַר לְפָנֶיךָ יוֹשֵׁב מָרוֹם, וּמַה נְּסַפֵּר לְפָנֶיךָ שׁוֹכֵן שְׁחָקִים, הֲלֹא הַנִּסְתָּרוֹת וְהַנִּגְלוֹת אַתָּה יוֹדֵעַ. אַתָּה יוֹדֵעַ רָזֵי עוֹלָם, וְתַעֲלוּמוֹת סִתְרֵי כָל חָי. אַתָּה חֹפֵשׂ כָּל חַדְרֵי בָטֶן, רֹאֶה כְלָיוֹת וָלֵב. אֵין דָּבָר נֶעְלָם מִמֶּךְּ, וְאֵין נִסְתָּר מִנֶּגֶד עֵינֶיךָ.\n\nיְהִי רָצוֹן מִלְּפָנֶיךָ, יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּמְחֹל לָנוּ אֶת כָּל חַטֹּאתֵינוּ, וּתְכַפֵּר לָנוּ אֶת כָּל עֲוׂנוֹתֵינוּ, וְתִמְחֹל וְתִסְלַח לְכָל פְּשָׁעֵינוּ. וְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ: סְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחֹל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ. כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח, וְרַב חֶסֶד לְכָל קֹרְאֶיךָ: לְמַעַן שִׁמְךָ יהוה, וְסָלַחְתָּ לַעֲוׂנִי כִּי רַב הוּא: לְמַעַן שִׁמְךָ יהוה תְּחַיֵּנִי, בְּצִדְקָתְךָ תּוצִיא מִצָּרָה נַפְשִׁי: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב, סֶלָה: יהוה צְבָאוֹת, אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ: הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם:","cond":["shacharitTachanun","monThu"]},{"kind":"text","text":"וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית, וְהִרְבָּה לְהָשִׁיב אַפּוֹ וְלֹא יָעִיר כָּל חֲמָתוֹ: אַתָּה יהוה, לֹא תִכְלָא רַחֲמֶיךָ מִמֶּנִּי, חַסְדְּךָ וַאֲמִתְּךָ תָּמִיד יִצְּרוּנִי: הוֹשִׁיעֵנוּ יהוה אֱלֹהֵינוּ וְקַבְּצֵנוּ מִן הַגּוֹיִם, לְהֹדוֹת לְשֵׁם קָדְשֶׁךָ, לְהִשְׁתַּבֵּחַ בִּתְהִלָּתֶךָ: אִם עֲוׂנוֹת תִּשְמָר יָהּ, אֲדֹנָי, מִי יַעֲמֹד: כִּי עִמְּךָ הַסְּלִיחָה, לְמַעַן תִּוָּרֵא: לֹא כַחֲטָאֵינוּ עָשָׂה לָנוּ, וְלֹא כַעֲוׂנֹתֵינוּ גָמַל עָלֵינוּ. אִם עֲוׂנֵינוּ עָנוּ בָנוּ, יהוה, עֲשֵׂה לְמַעַן שְׁמֶךָ. זְכֹר רַחֲמֶיךָ יהוה וַחֲסָדֶיךָ, כִּי מֵעוֹלָם הֵמָּה: יַעַנְךָ יהוה בְּיוֹם צָרָה, יְשַׂגֶּבְךָ שֵׁם אֱלֹהֵי יַעֲקֹב: יהוה הושִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ: אָבִינוּ מַלְכֵּנוּ, חָנֵּנוּ וַעֲנֵנוּ, כִּי אֵין בָּנוּ מַעֲשִׂים. עֲשֵׂה עִמָּנוּ צְדָקָה כְּרֹב רַחֲמֶיךָ, וְהוֹשִׁיעֵנוּ לְמַעַן שְׁמֶךָ.\n\nוְעַתָּה אֲדֹנָי אֱלֹהֵינוּ אֲשֶׁר הוֹצֵאתָ אֶת עַמְּךָ מֵאֶרֶץ מִצְרַיִם בְּיָד חֲזָקָה, וַתַּעַשׂ לְךָ שֵׁם כַּיּוֹם הַזֶּה, חָטָאנוּ רָשָׁעְנוּ: אֲדֹנָי, כְּכָל צִדְקֹתֶךָ יָשָׁב נָא אַפְּךָ וַחֲמָתְךָ מֵעִירְךָ יְרוּשָׁלַיִם הַר קָדְשֶׁךָ, כִּי בַחֲטָאֵינוּ וּבַעֲוׂנוֹת אֲבֹתֵינוּ, יְרוּשָׁלִַם וְעַמְּךָ לְחֶרְפָּה לְכָל סְבִיבֹתֵינוּ: וְעַתָּה שְׁמַע אֱלֹהֵינוּ אֶל תְּפִלַּת עַבְדְּךָ וְאֶל תַּחֲנוּנָיו, וְהָאֵר פָּנֶיךָ עַל מִקְדָּשְׁךָ הַשָּׁמֵם, לְמַעַן אֲדֹנָי: הַטֵּה אֱלֹהַי אָזְנְךָ וּשְׁמָע, פְּקַח עֵינֶיךָ וּרְאֵה שֹׁמְמֹתֵינוּ וְהָעִיר אֲשֶׁר נִקְרָא שִׁמְךָ עָלֶיהָ, כִּי לֹא עַל צִדְקֹתֵינוּ אֲנַחְנוּ מַפִּילִים תַּחֲנוּנֵינוּ לְפָנֶיךָ, כִּי עַל רַחֲמֶיךָ הָרַבִּים: אֲדֹנָי שְׁמָעָה, אֲדֹנָי סְלָחָה, אֲדֹנָי הַקֲשִׁיבָה וַעֲשֵׂה אַל תְּאַחַר, לְמַעֲנְךָ אֱלֹהַי, כִּי שִׁמְךָ נִקְרָא עַל עִירְךָ וְעַל עַמֶּךָ:\n\nאָבִינוּ אָב הָרַחֲמָן, הַרְאֵנוּ אוֹת לְטוֹבָה וְקַבֵּץ נְפוּצוֹתֵינוּ מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ. יַכִּירוּ וְיֵדְעוּ כָּל הַגּוֹיִם, כִּי אַתָּה יהוה אָבִינוּ אָתָּה, אֲנַחְנוּ הַחֹמֶר וְאַתָּה יֹצְרֵנוּ וּמַעֲשֵׂה יָדְךָ כֻּלָּנוּ: אָבִינוּ מַלְכֵּנוּ, צוּרֵנוּ מַלְכֵּנוּ וְגוֹאֲלֵנוּ, חוּסָה יהוה עַל עַמֶּךָ וְאַל תִּתֵּן נַחֲלָתְךָ לְחֶרְפָּה לִמְשָׁל בָּם גּוֹיִם, לָמָּה יֹאמְרוּ בָעַמִּים אַיֵּה אֱלֹהֵיהֶם: יָדַעְנוּ יהוה כִּי חָטָאנוּ וְאֵין מִי יַעֲמֹד בַּעֲדֵנוּ, אֶלָּא שִׁמְךָ הַגָּדוֹל יַעֲמָד לָנוּ בְּעֵת צָרָה. וּכְרַחֵם אָב עַל בָּנִים רַחֵם עָלֵינוּ. חֲמֹל עַל עַמָּךְ וְרַחֵם עַל נַחֲלָתָךְ, חוּסָה נָּא כְּרֹב רַחֲמֶיךָ, חָנֵנוּ מַלְכֵּנוּ וַעֲנֵנוּ. לְךָ יהוה הַצְּדָקָה, עֹשֵׂה נִפְלָאוֹת בְּכָל עֵת וָעֵת. הַבֵּט נָא וְהוֹשִׁיעָה נָּא צֹאן מַרְעִיתֶךָ. אַל יִמְשָׁל בָּנוּ קֶצֶף, כִּי לְךָ יהוה הַיְשׁוּעָה, בְּךָ תוֹחַלְתֵּנוּ. אֱלוֹהַּ סְלִיחוֹת, אָנָּא סְלַח נָא. כִּי אֵל טוֹב וְסַלָּח אָתָּה. אָנָּא מֶלֶךְ רַחוּם וְחַנּוּן, זְכֹר וְהַבֵּט לִבְרִית בֵּין הַבְּתָרִים, וְתֵרָאֶה לְפָנֶיךָ עֲקֵדַת יָחִיד. וּלְמַעַן יִשרָאֵל אָבִינוּ, אַל תַּעַזְבִנוּ אָבִינוּ וְאַל תִּטְּשֵנוּ מַלְכֵּנוּ, וְאַל תִּשְׁכָּחֵנוּ יוֹצְרֵנוּ, וְאַל תַּעַשׂ עִמָּנוּ כָלָה בְּגָלוּתֵנוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.\n\nאֵין כָּמוֹך חַנּוּן וְרַחוּם, אֱלֹהֵינוּ, אֵין כָּמוֹךָ אֵל אֶרֶך אַפַּיִם וְרַב חֶסֶד וֶאֱמֶת. הוֹשִׁיעֵנוּ וְרַחֲמֵנוּ, מֵרַעַשׁ וּמֵרֹגֶז הַצִּילֵנוּ. זְכֹר לַעֲבָדֶיך לְאַבְרָהָם לְיִצְחָק וּלְיַעֲקֹב, אַל תֵּפֶן אֶל קְשִׁי הָעָם הַזֶּה וְאֶל רִשְׁעוֹ וְאֶל חַטָּאתוֹ: שׁוּב מֵחָרוֹן אַפֶּךָ, וְהִנָּחֵם עַל הָרָעָה לְעַמֶּךָ: וְהָסֵר מִמֶּנּוּ מַכַּת הַמָּוֶת כִּי רַחוּם אָתָּה, כִּי כֵן דַּרְכְּךָ לַעֲשׂוֹת חֶסֶד חִנָּם בְּכָל דוֹר וָדוֹר. אָנָּא יהוה הוֹשִׁיעָה נָּא, אָנָּא יהוה הַצְלִיחָה נָּא: אָנָּא יהוה עֲנֵנוּ בְיוֹם קָרְאֵנוּ. לְךָ יהוה קִוִּינוּ, לְךָ יהוה חִכִּינוּ, לְךָ יהוה נְיַחֵל, אַל תֶּחֱשֶׁה וּתְעַנֵּנוּ, כִּי נַאֲמוּ גוֹיִם: אָבְדָה תִקְוָתָם. כָּל בֶּרֶך לְךָ תִּכְרַע, וְכָל קוֹמָה לְפָנֶיךָ תִּשְׁתַּחֲוֶה.\n\nהַפּוֹתֵחַ יָד בִּתְשׁוּבַה לְקַבֵּל פּוֹשְׁעִים וְחַטָּאִים, נִבְהֲלָה נַפְשֵׁנוּ מֵרֹב עִצְּבוֹנֵנוּ. אַל תִּשְׁכָּחֵנוּ נֶצַח, קוּמָה וְהוֹשִׁיעֵנוּ. אַל תִּשְׁפֹּך חֲרוֹנְךָ עָלֵינוּ, כִּי עַמְּךָ אֲנַחְנוּ בְּנֵי בְרִיתֶךָ. אֵל, הַבִּיטָה, דַּל כְּבוֹדֵנוּ בַּגּוֹיִם וְשִׁקְּצוּנוּ כְּטֻמְאַת הַנִּדָּה. עַד מַתָּי עֻזְּךָ בַשְּׁבִי, וְתִפְאַרְתְּךָ בְיַד צָר? הֵמָה יִרְאוּ וְיֵבֹשׁוּ וְיֵחַתּוּ מִגְּבוּרָתָם. עוֹרְרָה גְבוּרָתֶךָ, וְהוֹשִׁיעֵנוּ לְמַעַן שְׁמֶךָ. אַל יִמְעֲטוּ לְפָנֶיךָ תְּלָאוֹתֵינוּ, מַהֵר יְקַדְּמוּנוּ רַחֲמֶיךָ בְּעֵת צָרוֹתֵינוּ. לֹא לְמַעֲנֵנוּ, אֶלָּא לְמַעַנְךָ פְעֹל, וְאַל תַּשְׁחִית אֶת זֵכֶר שְׁאֵרִיתֵנוּ, כִּי לְךָ מְיַחֲלוֹת עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה. וּזְכֹר לָנוּ עֵדוּתֵנוּ בְכָל יוֹם תָּמִיד אוֹמְרִים פַּעֲמַיִם בְּאַהֲבָה: \"שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:\"","cond":["shacharitTachanun","monThu"]},{"kind":"header","text":"סדר נטילת לולב","cond":["sucot"]},{"kind":"instruction","text":"סדר נטילת לולב\n\nיקח את הלולב, ההדסים והערבות בידו הימנית כאשר שדרת הלולב תפנה אליו, והם מצביעים למעלה \"כדרך גידולם\". את האתרוג ייקח בידו השמאלית ויחזיקו הפוך, כלומר העוקץ (מיקום חיבורו לעץ) מופנה כלפי מעלה.","cond":["sucot"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ עַל נְטִילַת לוּלָב.","cond":["sucot"]},{"kind":"text","text":"בָּרוּךְ אַָתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁהֶחֱיָנוּ וְקִיְּמָנוּ וְהִגִּיעָנוּ לַזְּמַן הַזֶּה.","cond":["sucot","lulav_shehecheyanu"]},{"kind":"instruction","text":"לאחר הברכה הופכים את האתרוג ומחזיקים אותו כדרך גידולו כך שהפיטם פונה כלפי מעלה. לאחר מכן מקרבים את הלולב והאתרוג יחד ומנענעים אותם לכל הכיוונים.","cond":["sucot"]},{"kind":"header","text":"הלל","cond":["hallel"]},{"kind":"instruction","text":"הלל","cond":["hallel"]},{"kind":"instruction","text":"יש המברכים על הלל ביום העצמאות וביום שחרור ירושלים ויש שאינם מברכים, ויש שאינם אומרים הלל כלל בימים אלה.","cond":["hallel","yerushalayim"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ לִגְמֹר אֶת הַהַלֵּל.","cond":["hallel","fullHallel"]},{"kind":"text","text":"הַלְלוּיָהּ, הַלְלוּ עַבְדֵי יהוה, הַלְלוּ אֶת שֵׁם יהוה: יְהִי שֵׁם יהוה מְבֹרָךְ מֵעַתָּה וְעַד עוֹלָם: מִמִּזְרַח שֶׁמֶשׁ עַד מְבוֹאוֹ מְהֻלָּל שֵׁם יהוה: רָם עַל כָּל גּוֹיִם יהוה, עַל הַשָּׁמַיִם כְּבוֹדוֹ: מִי כַּיהוה אֱלֹהֵינוּ הַמַּגְבִּיהִי לָשָׁבֶת: הַמַּשְׁפִּילִי לִרְאוֹת בַּשָּׁמַיִם וּבָאָרֶץ: מְקִימִי מֵעָפָר דָּל, מֵאַשְׁפֹּת יָרִים אֶבְיוֹן: לְהוֹשִׁיבִי עִם נְדִיבִים, עִם נְדִיבֵי עַמּוֹ: מוֹשִׁיבִי עֲקֶרֶת הַבַּיִת, אֵם הַבָּנִים שְׂמֵחָה הַלְלוּיָהּ:","cond":["hallel"]},{"kind":"text","text":"בְּצֵאת יִשְׂרָאֵל מִמִּצְרָיִם, בֵּית יַעֲקֹב מֵעַם לֹעֵז: הָיְתָה יְהוּדָה לְקָדְשׁוֹ, יִשְׂרָאֵל מַמְשְׁלוֹתָיו: הַיָּם רָאָה וַיָּנֹס, הַיַּרְדֵּן יִסֹּב לְאָחוֹר: הֶהָרִים רָקְדוּ כְאֵילִים, גְּבָעוֹת כִּבְנֵי צֹאן: מַה לְּךָ הַיָּם כִּי תָנוּס, הַיַּרְדֵּן תִּסֹּב לְאָחוֹר: הֶהָרִים תִּרְקְדוּ כְאֵילִים, גְּבָעוֹת כִּבְנֵי צֹאן: מִלִּפְנֵי אָדוֹן חוּלִי אָרֶץ, מִלִּפְנֵי אֱלוֹהַּ יַעֲקֹב: הַהֹפְכִי הַצּוּר אֲגַם מָיִם, חַלָּמִישׁ לְמַעְיְנוֹ מָיִם:","cond":["hallel"]},{"kind":"text","text":"לֹא לָנוּ, יהוה, לֹא לָנוּ, כִּי לְשִׁמְךָ תֵּן כָּבוֹד עַל חַסְדְּךָ עַל אֲמִתֶּךָ: לָמָּה יֹאמְרוּ הַגּוֹיִם אַיֵּה נָא אֱלֹהֵיהֶם: וֵאלֹהֵינוּ בַשָּׁמָיִם כֹּל אֲשֶׁר חָפֵץ עָשָׂה: עֲצַבֵּיהֶם כֶּסֶף וְזָהָב, מַעֲשֵׂה יְדֵי אָדָם: פֶּה לָהֶם וְלֹא יְדַבֵּרוּ, עֵינַיִם לָהֶם וְלֹא יִרְאוּ: אָזְנַיִם לָהֶם וְלֹא יִשְׁמָעוּ, אַף לָהֶם וְלֹא יְרִיחוּן: יְדֵיהֶם וְלֹא יְמִישׁוּן, רַגְלֵיהֶם וְלֹא יְהַלֵּכוּ, לֹא יֶהְגּוּ בִּגְרוֹנָם: כְּמוֹהֶם יִהְיוּ עֹשֵׂיהֶם, כֹּל אֲשֶׁר בֹּטֵחַ בָּהֶם: יִשְׂרָאֵל בְּטַח בַּיהוה, עֶזְרָם וּמָגִנָּם הוּא: בֵּית אַהֲרֹן בִּטְחוּ בַיהוה, עֶזְרָם וּמָגִנָּם הוּא: יִרְאֵי יהוה בִּטְחוּ בַיהוה, עֶזְרָם וּמָגִנָּם הוּא:","cond":["hallel","fullHallel"]},{"kind":"text","text":"יהוה זְכָרָנוּ יְבָרֵךְ, יְבָרֵךְ אֶת בֵּית יִשְׂרָאֵל, יְבָרֵךְ אֶת בֵּית אַהֲרֹן: יְבָרֵךְ יִרְאֵי יהוה, הַקְּטַנִּים עִם הַגְּדֹלִים: יֹסֵף יהוה עֲלֵיכֶם, עֲלֵיכֶם וְעַל בְּנֵיכֶם: בְּרוּכִים אַתֶּם לַיהוה, עֹשֵׂה שָׁמַיִם וָאָרֶץ: הַשָּׁמַיִם שָׁמַיִם לַיהוה, וְהָאָרֶץ נָתַן לִבְנֵי אָדָם: לֹא הַמֵּתִים יְהַלְלוּ יָהּ, וְלֹא כָּל יֹרְדֵי דוּמָה: וַאֲנַחְנוּ נְבָרֵךְ יָהּ מֵעַתָּה וְעַד עוֹלָם הַלְלוּיָהּ:","cond":["hallel"]},{"kind":"text","text":"אָהַבְתִּי כִּי יִשְׁמַע יהוה אֶת קוֹלִי תַּחֲנוּנָי: כִּי הִטָּה אָזְנוֹ לִי וּבְיָמַי אֶקְרָא: אֲפָפוּנִי חֶבְלֵי מָוֶת וּמְצָרֵי שְׁאוֹל מְצָאוּנִי, צָרָה וְיָגוֹן אֶמְצָא: וּבְשֵׁם יהוה אֶקְרָא, אָנָּה יהוה מַלְּטָה נַפְשִׁי: חַנּוּן יהוה וְצַדִּיק, וֵאלֹהֵינוּ מְרַחֵם: שֹׁמֵר פְּתָאיִם יהוה, דַּלּוֹתִי וְלִי יְהוֹשִׁיעַ: שׁוּבִי נַפְשִׁי לִמְנוּחָיְכִי כִּי יהוה גָּמַל עָלָיְכִי: כִּי חִלַּצְתָּ נַפְשִׁי מִמָּוֶת, אֶת עֵינִי מִן דִּמְעָה, אֶת רַגְלִי מִדֶּחִי: אֶתְהַלֵּךְ לִפְנֵי יהוה בְּאַרְצוֹת הַחַיִּים: הֶאֱמַנְתִּי כִּי אֲדַבֵּר אֲנִי עָנִיתִי מְאֹד: אֲנִי אָמַרְתִּי בְחָפְזִי כָּל הָאָדָם כֹּזֵב:","cond":["hallel","fullHallel"]},{"kind":"text","text":"מָה אָשִׁיב לַיהוה, כָּל תַּגְמוּלוֹהִי עָלָי: כּוֹס יְשׁוּעוֹת אֶשָּׂא, וּבְשֵׁם יהוה אֶקְרָא: נְדָרַי לַיהוה אֲשַׁלֵּם, נֶגְדָה נָּא לְכָל עַמּוֹ: יָקָר בְּעֵינֵי יהוה הַמָּוְתָה לַחֲסִידָיו: אָנָּה יהוה כִּי אֲנִי עַבְדֶּךָ, אֲנִי עַבְדְּךָ בֶּן אֲמָתֶךָ, פִּתַּחְתָּ לְמוֹסֵרָי: לְךָ אֶזְבַּח זֶבַח תּוֹדָה, וּבְשֵׁם יהוה אֶקְרָא: נְדָרַי לַיהוה אֲשַׁלֵּם, נֶגְדָה נָּא לְכָל עַמּוֹ: בְּחַצְרוֹת בֵּית יהוה, בְּתוֹכֵכִי יְרוּשָׁלָיִם הַלְלוּיָהּ:","cond":["hallel"]},{"kind":"text","text":"הַלְלוּ אֶת יהוה כָּל גּוֹיִם, שַׁבְּחוּהוּ כָּל הָאֻמִּים: כִּי גָבַר עָלֵינוּ חַסְדּוֹ, וֶאֱמֶת יהוה לְעוֹלָם הַלְלוּיָהּ:","cond":["hallel"]},{"kind":"instruction","text":"ארבעה פסוקים אלה אומר החזן פסוק פסוק והקהל עונה \"הוֹדוּ לַה'...\". ויש האומרים בלחש יחד עם החזן את הפסוק שהוא אומר. ויש בכך מנהגים שונים.","cond":["hallel"]},{"kind":"text","text":"הוֹדוּ לַיהוה כִּי טוֹב, כִּי לְעוֹלָם חַסְדּוֹ:\nיֹאמַר נָא יִשְׂרָאֵל, כִּי לְעוֹלָם חַסְדּוֹ:\nיֹאמְרוּ נָא בֵית אַהֲרֹן, כִּי לְעוֹלָם חַסְדּוֹ:\nיֹאמְרוּ נָא יִרְאֵי יהוה, כִּי לְעוֹלָם חַסְדּוֹ:","cond":["hallel"]},{"kind":"text","text":"מִן הַמֵּצַר קָרָאתִי יָהּ, עָנָנִי בַמֶּרְחָב יָהּ: יהוה לִי לֹא אִירָא, מַה יַּעֲשֶׂה לִי אָדָם: יהוה לִי בְּעֹזְרָי, וַאֲנִי אֶרְאֶה בְשֹׂנְאָי: טוֹב לַחֲסוֹת בַּיהוה מִבְּטֹחַ בָּאָדָם: טוֹב לַחֲסוֹת בַּיהוה מִבְּטֹחַ בִּנְדִיבִים: כָּל גּוֹיִם סְבָבוּנִי בְּשֵׁם יהוה כִּי אֲמִילַם: סַבּוּנִי גַם סְבָבוּנִי בְּשֵׁם יהוה כִּי אֲמִילַם: סַבּוּנִי כִדְבוֹרִים דֹּעֲכוּ כְּאֵשׁ קוֹצִים בְּשֵׁם יהוה כִּי אֲמִילַם: דַּחֹה דְחִיתַנִי לִנְפֹּל וַיהוה עֲזָרָנִי: עָזִּי וְזִמְרָת יָהּ וַיְהִי לִי לִישׁוּעָה: קוֹל רִנָּה וִישׁוּעָה בְּאָהֳלֵי צַדִּיקִים, יְמִין יהוה עֹשָׂה חָיִל: יְמִין יהוה רוֹמֵמָה, יְמִין יהוה עֹשָׂה חָיִל: לֹא אָמוּת כִּי אֶחְיֶה וַאֲסַפֵּר מַעֲשֵׂי יָהּ: יַסֹּר יִסְּרַנִּי יָּהּ וְלַמָּוֶת לֹא נְתָנָנִי: פִּתְחוּ לִי שַׁעֲרֵי צֶדֶק, אָבֹא בָם אוֹדֶה יָהּ: זֶה הַשַּׁעַר לַיהוה, צַדִּיקִים יָבֹאוּ בוֹ:","cond":["hallel"]},{"kind":"text","text":"אוֹדְךָ כִּי עֲנִיתָנִי וַתְּהִי לִי לִישׁוּעָה:\nאוֹדְךָ כִּי עֲנִיתָנִי וַתְּהִי לִי לִישׁוּעָה:\n\nאֶבֶן מָאֲסוּ הַבּוֹנִים, הָיְתָה לְרֹאשׁ פִּנָּה:\nאֶבֶן מָאֲסוּ הַבּוֹנִים, הָיְתָה לְרֹאשׁ פִּנָּה:\n\nמֵאֵת יהוה הָיְתָה זֹּאת, הִיא נִפְלָאת בְּעֵינֵינוּ:\nמֵאֵת יהוה הָיְתָה זֹּאת, הִיא נִפְלָאת בְּעֵינֵינוּ:\n\nזֶה הַיּוֹם עָשָׂה יהוה, נָגִילָה וְנִשְׂמְחָה בוֹ:\nזֶה הַיּוֹם עָשָׂה יהוה, נָגִילָה וְנִשְׂמְחָה בוֹ:","cond":["hallel"]},{"kind":"instruction","text":"פסוק \"אָנָּא יהוה הוֹשִׁיעָה נָּא, אָנָּא יהוה הַצְלִיחָה נָּא\" נחלק לשניים, ואומרים כל חלק פעמיים. נוהגים שהחזן אומר חלק והקהל חוזר אחריו.","cond":["hallel"]},{"kind":"text","text":"אָנָּא יהוה הוֹשִׁיעָה נָּא.\nאָנָּא יהוה הוֹשִׁיעָה נָּא.\n\nאָנָּא יהוה הַצְלִיחָה נָּא:\nאָנָּא יהוה הַצְלִיחָה נָּא:","cond":["hallel"]},{"kind":"text","text":"בָּרוּךְ הַבָּא בְּשֵׁם יהוה, בֵּרַכְנוּכֶם מִבֵּית יהוה:\nבָּרוּךְ הַבָּא בְּשֵׁם יהוה, בֵּרַכְנוּכֶם מִבֵּית יהוה:\n\nאֵל יהוה וַיָּאֶר לָנוּ אִסְרוּ חַג בַּעֲבֹתִים עַד קַרְנוֹת הַמִּזְבֵּחַ:\nאֵל יהוה וַיָּאֶר לָנוּ אִסְרוּ חַג בַּעֲבֹתִים עַד קַרְנוֹת הַמִּזְבֵּחַ:\n\nאֵלִי אַתָּה וְאוֹדֶךָּ, אֱלֹהַי אֲרוֹמְמֶךָּ:\nאֵלִי אַתָּה וְאוֹדֶךָּ, אֱלֹהַי אֲרוֹמְמֶךָּ:\n\nהוֹדוּ לַיהוה כִּי טוֹב, כִּי לְעוֹלָם חַסְדּוֹ:\nהוֹדוּ לַיהוה כִּי טוֹב, כִּי לְעוֹלָם חַסְדּוֹ:","cond":["hallel"]},{"kind":"text","text":"יְהַלְלוּךָ יהוה אֱלֹהֵינוּ כָּל מַעֲשֶׂיךָ, וַחֲסִידֶיךָ וְצַדִּיקִים עוֹשֵׂי רְצוֹנֶךָ וְעַמְּךָ בֵית יִשְׂרָאֵל, כֻּלָּם בְּרִנָּה יוֹדוּ וִיבָרְכוּ וִישַׁבְּחוּ וִיפָאֲרוּ אֶת-שֵׁם כְּבוֹדֶךָ. כִּי לְךָ טוֹב לְהוֹדוֹת, וּלְשִׁמְךָ נָעִים לְזַמֵּר, וּמֵעוֹלָם עַד עוֹלָם אַתָּה אֵל. בָּרוּךְ אַתָּה יהוה, מֶלֶךְ מְהֻלָּל בַּתִּשְׁבָּחוֹת. אָמֵן.","cond":["hallel","fullHallel"]},{"kind":"instruction","text":"קדיש תתקבל","cond":["hallel","musaf"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.\nתִּתְקַבַּל צְלוֹתָנָא וּבָעוּתָנָא עִם צְלוֹתְהוֹן וּבָעוּתְהוֹן דְּכָל בֵּית יִשְׂרָאֵל קֳדָם אֲבוּנָא דְבִשְׁמַיָּא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא, חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה וְשֵיזָבָא וּרְפוּאָה וּגְאֻלָּה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה, לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["hallel","musaf"]},{"kind":"text","text":"עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["hallel","musaf","noayt"]},{"kind":"special","text":"עֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["hallel","musaf","ayt"]},{"kind":"instruction","text":"חצי קדיש","cond":["noMusaf"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noMusaf"]},{"kind":"header","text":"הוצאת ספר תורה","cond":["tora"]},{"kind":"instruction","text":"הוצאת ספר תורה","cond":["tora"]},{"kind":"text","text":"גַּדְּלוּ לַיהוה אִתִּי, וּנְרוֹמְמָה שְׁמוֹ יַחְדָּו: רוֹמְמוּ יהוה אֱלֹהֵינוּ, וְהִשְׁתַּחֲווּ לַהֲדֹם רַגְלָיו, קָדוֹשׁ הוּא: רוֹמְמוּ יהוה אֱלֹהֵינוּ וְהִשְׁתַּחֲווּ לְהַר קָדְשׁוֹ, כִּי קָדוֹשׁ יהוה אֱלֹהֵינוּ: אֵין קָדוֹשׁ כַּיהוה כִּי אֵין בִּלְתֶּךָ. וְאֵין צוּר כֵּאלֹהֵינוּ: כִּי מִי אֱלוֹהַּ מִבַּלְעֲדֵי יהוה, וּמִי צוּר זוּלָתִי אֱלֹהֵינוּ: תּוֹרָה צִוָּה לָנוּ מֹשֶׁה, מוֹרָשָׁה קְהִלַּת יַעֲקֹב: עֵץ חַיִּים הִיא לַמַּחֲזִיקִים בָּהּ, וְתוֹמְכֶיהָ מְאֻשָּׁר: דְּרָכֶיהָ דַרְכֵי נֹעַם וְכָל נְתִיבוֹתֶיהָ שָׁלוֹם: שָׁלוֹם רָב לְאוֹהֲבֵי תוֹרָתֶךָ וְאֵין לָמו מִכְשׁוֹל: יהוה עֹז לְעַמּוֹ יִתֵּן, יהוה יְבָרֵךְ אֶת עַמּוֹ בַשָּׁלוֹם: כִּי שֵׁם יהוה אֶקְרָא, הָבוּ גֹדֶל לֵאלֹהֵינוּ: הַכֹּל תְּנוּ עֹז לֵאלֹהִים וּתְנוּ כָבוֹד לַתּוֹרָה.","cond":["tora"]},{"kind":"instruction","text":"ומגביה ספר תורה ומראה הכתב לקהל ואומרים:","cond":["tora"]},{"kind":"text","text":"וְזֹאת הַתּוֹרָה אֲשֶׁר שָׂם מֹשֶׁה לִפְנֵי בְּנֵי יִשְׂרָאֵל: תּוֹרָה צִוָּה לָנוּ מֹשֶׁה, מוֹרָשָׁה קְהִלַּת יַעֲקֹב: הָאֵל, תָּמִים דַּרְכּוֹ, אִמְרַת יהוה צְרוּפָה, מָגֵן הוּא לְכָל הַחֹסִים בּוֹ:","cond":["tora"]},{"kind":"header","text":"קריאת התורה","cond":["tora"]},{"kind":"instruction","text":"קריאת התורה","cond":["tora"]},{"kind":"text","text":"=====","cond":["tora"]},{"kind":"header","text":"ברכת הגומל","cond":["tora"]},{"kind":"instruction","text":"ברכת הגומל","cond":["tora"]},{"kind":"text","text":"אוֹדֶה יהוה בְּכָל לֵבָב, בְּסוֹד יְשָׁרִים וְעֵדָה:\n\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַגּוֹמֵל לְחַיָּבִים טוֹבוֹת, שֶׁגְּמָלַנִי כָּל טוּב.","cond":["tora"]},{"kind":"instruction","text":"והקהל עונים:","cond":["tora"]},{"kind":"text","text":"הָאֵל שֶׁגְּמָלָךְ כָּל טוּב, הוּא יִגְמָלְךָ כָּל טוּב סֶלָה.","cond":["tora"]},{"kind":"instruction","text":"והוא עונה אחריהם:","cond":["tora"]},{"kind":"text","text":"אָמֵן, כֵּן יְהִי רָצוֹן.","cond":["tora"]},{"kind":"instruction","text":"חצי קדיש","cond":["tora"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["tora"]},{"kind":"header","text":"הפטרה","cond":["tishaaBeav"]},{"kind":"instruction","text":"הפטרה","cond":["tishaaBeav"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר בָּחַר בִּנְבִיאִים טוֹבִים וְרָצָה בְדִבְרֵיהֶם הַנֶּאֱמָרִים בֶּאֱמֶת. בָּרוּךְ אַתָּה יהוה, הַבּוֹחֵר בַּתּוֹרָה וּבְמֹשֶׁה עַבְדּוֹ וּבְיִשְׂרָאֵל עַמּוֹ וּבִנְבִיאֵי הָאֱמֶת וָצֶדֶק.\n\nאָסֹף אֲסִיפֵם נְאֻם יהוה אֵין עֲנָבִים בַּגֶּפֶן וְאֵין תְּאֵנִים בַּתְּאֵנָה וְהֶעָלֶה נָבֵל וָאֶתֵּן לָהֶם יַעַבְרוּם: עַל מָה אֲנַחְנוּ יֹשְׁבִים הֵאָסְפוּ וְנָבוֹא אֶל עָרֵי הַמִּבְצָר וְנִדְּמָה שָּׁם כִּי יהוה אֱלֹהֵינוּ הֲדִמָּנוּ וַיַּשְׁקֵנוּ מֵי רֹאשׁ כִּי חָטָאנוּ לַיהוה: קַוֵּה לְשָׁלוֹם וְאֵין טוֹב לְעֵת מַרְפֵּה וְהִנֵּה בְעָתָה: מִדָּן נִשְׁמַע נַחְרַת סוּסָיו מִקּוֹל מִצְהֲלוֹת אַבִּירָיו רָעֲשָׁה כָּל הָאָרֶץ וַיָּבוֹאוּ וַיֹּאכְלוּ אֶרֶץ וּמְלוֹאָהּ עִיר וְיֹשְׁבֵי בָהּ: כִּי הִנְנִי מְשַׁלֵּחַ בָּכֶם נְחָשִׁים צִפְעֹנִים אֲשֶׁר אֵין לָהֶם לָחַשׁ וְנִשְּׁכוּ אֶתְכֶם נְאֻם יהוה: מַבְלִיגִיתִי עֲלֵי יָגוֹן עָלַי לִבִּי דַוָּי: הִנֵּה קוֹל שַׁוְעַת בַּת עַמִּי מֵאֶרֶץ מַרְחַקִּים הַיהוה אֵין בְּצִיּוֹן אִם מַלְכָּהּ אֵין בָּהּ מַדּוּעַ הִכְעִסוּנִי בִּפְסִלֵיהֶם בְּהַבְלֵי נֵכָר: עָבַר קָצִיר כָּלָה קָיִץ וַאֲנַחְנוּ לוֹא נוֹשָׁעְנוּ: עַל שֶׁבֶר בַּת עַמִּי הָשְׁבָּרְתִּי קָדַרְתִּי שַׁמָּה הֶחֱזִקָתְנִי: הַצֳרִי אֵין בְּגִלְעָד אִם רֹפֵא אֵין שָׁם כִּי מַדּוּעַ לֹא עָלְתָה אֲרֻכַת בַּת עַמִּי: מִי יִתֵּן רֹאשִׁי מַיִם וְעֵינִי מְקוֹר דִּמְעָה וְאֶבְכֶּה יוֹמָם וָלַיְלָה אֵת חַלְלֵי בַת עַמִּי: מִי יִתְּנֵנִי בַמִּדְבָּר מְלוֹן אֹרְחִים וְאֶעֶזְבָה אֶת עַמִּי וְאֵלְכָה מֵאִתָּם כִּי כֻלָּם מְנָאֲפִים עֲצֶרֶת בֹּגְדִים: וַיַּדְרְכוּ אֶת לְשׁוֹנָם קַשְׁתָּם שֶׁקֶר וְלֹא לֶאֱמוּנָה גָּבְרוּ בָאָרֶץ כִּי מֵרָעָה אֶל רָעָה יָצָאוּ וְאֹתִי לֹא יָדָעוּ נְאֻם יהוה: אִישׁ מֵרֵעֵהוּ הִשָּׁמֵרוּ וְעַל כָּל אָח אַל תִּבְטָחוּ כִּי כָל אָח עָקוֹב יַעְקֹב וְכָל רֵעַ רָכִיל יַהֲלֹךְ: וְאִישׁ בְּרֵעֵהוּ יְהָתֵלּוּ וֶאֱמֶת לֹא יְדַבֵּרוּ לִמְּדוּ לְשׁוֹנָם דַּבֶּר שֶׁקֶר הַעֲוֵה נִלְאוּ: שִׁבְתְּךָ בְּתוֹךְ מִרְמָה בְּמִרְמָה מֵאֲנוּ דַעַת אוֹתִי נְאֻם יהוה: לָכֵן כֹּה אָמַר יהוה צְבָאוֹת הִנְנִי צוֹרְפָם וּבְחַנְתִּים כִּי אֵיךְ אֶעֱשֶׂה מִפְּנֵי בַּת עַמִּי: חֵץ שָׁחוּט לְשׁוֹנָם מִרְמָה דִבֵּר בְּפִיו שָׁלוֹם אֶת רֵעֵהוּ יְדַבֵּר וּבְקִרְבּוֹ יָשִׂים אָרְבּוֹ: הַעַל אֵלֶּה לֹא אֶפְקָד בָּם נְאֻם יהוה אִם בְּגוֹי אֲשֶׁר כָּזֶה לֹא תִתְנַקֵּם נַפְשִׁי: עַל הֶהָרִים אֶשָּׂא בְכִי וָנֶהִי וְעַל נְאוֹת מִדְבָּר קִינָה כִּי נִצְּתוּ מִבְּלִי אִישׁ עֹבֵר וְלֹא שָׁמְעוּ קוֹל מִקְנֶה מֵעוֹף הַשָּׁמַיִם וְעַד בְּהֵמָה נָדְדוּ הָלָכוּ: וְנָתַתִּי אֶת יְרוּשָׁלַיִם לְגַלִּים מְעוֹן תַּנִּים וְאֶת עָרֵי יְהוּדָה אֶתֵּן שְׁמָמָה מִבְּלִי יוֹשֵׁב: מִי הָאִישׁ הֶחָכָם וְיָבֵן אֶת זֹאת וַאֲשֶׁר דִּבֶּר פִּי יהוה אֵלָיו וְיַגִּדָהּ עַל מָה אָבְדָה הָאָרֶץ נִצְּתָה כַמִּדְבָּר מִבְּלִי עֹבֵר: וַיֹּאמֶר יהוה עַל עָזְבָם אֶת תּוֹרָתִי אֲשֶׁר נָתַתִּי לִפְנֵיהֶם וְלֹא שָׁמְעוּ בְקוֹלִי וְלֹא הָלְכוּ בָהּ: וַיֵּלְכוּ אַחֲרֵי שְׁרִרוּת לִבָּם וְאַחֲרֵי הַבְּעָלִים אֲשֶׁר לִמְּדוּם אֲבוֹתָם: לָכֵן כֹּה אָמַר יהוה צְבָאוֹת אֱלֹהֵי יִשְׂרָאֵל הִנְנִי מַאֲכִילָם אֶת הָעָם הַזֶּה לַעֲנָה וְהִשְׁקִיתִים מֵי רֹאשׁ: וַהֲפִצוֹתִים בַּגּוֹיִם אֲשֶׁר לֹא יָדְעוּ הֵמָּה וַאֲבוֹתָם וְשִׁלַּחְתִּי אַחֲרֵיהֶם אֶת הַחֶרֶב עַד כַּלּוֹתִי אוֹתָם: כֹּה אָמַר יהוה צְבָאוֹת הִתְבּוֹנְנוּ וְקִרְאוּ לַמְקוֹנְנוֹת וּתְבוֹאֶינָה וְאֶל הַחֲכָמוֹת שִׁלְחוּ וְתָבוֹאנָה: וּתְמַהֵרְנָה וְתִשֶּׂנָה עָלֵינוּ נֶהִי וְתֵרַדְנָה עֵינֵינוּ דִּמְעָה וְעַפְעַפֵּינוּ יִזְּלוּ מָיִם: כִּי קוֹל נְהִי נִשְׁמַע מִצִּיּוֹן אֵיךְ שֻׁדָּדְנוּ בֹּשְׁנוּ מְאֹד כִּי עָזַבְנוּ אָרֶץ כִּי הִשְׁלִיכוּ מִשְׁכְּנוֹתֵינוּ: כִּי שְׁמַעְנָה נָשִׁים דְּבַר יהוה וְתִקַּח אָזְנְכֶם דְּבַר פִּיו וְלַמֵּדְנָה בְנוֹתֵיכֶם נֶהִי וְאִשָּׁה רְעוּתָהּ קִינָה: כִּי עָלָה מָוֶת בְּחַלּוֹנֵינוּ בָּא בְּאַרְמְנוֹתֵינוּ לְהַכְרִית עוֹלָל מִחוּץ בַּחוּרִים מֵרְחֹבוֹת: דַּבֵּר כֹּה נְאֻם יהוה וְנָפְלָה נִבְלַת הָאָדָם כְּדֹמֶן עַל פְּנֵי הַשָּׂדֶה וּכְעָמִיר מֵאַחֲרֵי הַקֹּצֵר וְאֵין מְאַסֵּף: כֹּה אָמַר יהוה אַל יִתְהַלֵּל חָכָם בְּחָכְמָתוֹ וְאַל יִתְהַלֵּל הַגִּבּוֹר בִּגְבוּרָתוֹ אַל יִתְהַלֵּל עָשִׁיר בְּעָשְׁרוֹ: כִּי אִם בְּזֹאת יִתְהַלֵּל הַמִּתְהַלֵּל הַשְׂכֵּל וְיָדֹעַ אוֹתִי כִּי אֲנִי יהוה עֹשֶׂה חֶסֶד מִשְׁפָּט וּצְדָקָה בָּאָרֶץ כִּי בְאֵלֶּה חָפַצְתִּי נְאֻם יהוה:\n\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעולָם, צוּר כָּל הָעוֹלָמִים, צַדִּיק בְּכָל הַדּוֹרוֹת, הָאֵל הַנֶּאֱמָן הָאוֹמֵר וְעוֹשֶׂה, הַמְדַבֵּר וּמְקַיֵּם שֶׁכָּל דְּבָרָיו אֱמֶת וָצֶדֶק. נֶאֱמָן אַתָּה הוּא יהוה אֱלֹהֵינוּ וְנֶאֱמָנִים דְּבָרֶיךָ, וְדָבָר אֶחָד מִדְּבָרֶיךָ אָחוֹר לֹא יָשׁוּב רֵיקָם, כִּי אֵל מֶלֶךְ נֶאֱמָן וְרַחֲמָן אָתָּה. בָּרוּךְ אַתָּה יהוה, הָאֵל הַנֶּאֱמָן בְּכָל דְּבָרָיו.\n\nרַחֵם עַל צִיּוֹן כִּי הִיא בֵּית חַיֵּינוּ, וְלַעֲלוּבַת נֶפֶשׁ תּוֹשִׁיעַ בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יהוה, מְשַׂמֵּחַ צִיּוֹן בְּבָנֶיהָ.\n\nשַׂמְּחֵנוּ יהוה אֱלֹהֵינוּ בְּאֵלִיָּהוּ הַנָּבִיא עַבְדֶּךָ וּבְמַלְכוּת בֵּית דָּוִד מְשִׁיחֶךָ, בִּמְהֵרָה יָבוֹא וְיָגֵל לִבֵּנוּ, עַל כִּסְאוֹ לֹא יֵשֵׁב זָר וְלֹא יִנְחֲלוּ עוֹד אֲחֵרִים אֶת כְּבוֹדוֹ, כִּי בְשֵׁם קָדְשְׁךָ נִשְׁבַּעְתָּ לוֹ שֶׁלֹּא יִכְבֶּה נֵרוֹ לְעוֹלָם וָעֶד. בָּרוּךְ אַתָּה יהוה, מָגֵן דָּוִד.","cond":["tishaaBeav"]},{"kind":"header","text":"אשרי ובא לציון","cond":[]},{"kind":"text","text":"אַשְׁרֵי יוֹשְׁבֵי בֵיתֶךָ עוֹד יְהַלְלוּךָ סֶּלָה:\nאַשְׁרֵי הָעָם שֶׁכָּכָה לּוֹ אַשְׁרֵי הָעָם שֶׁיהוה אֱלֹהָיו:\nתְּהִלָּה לְדָוִד, אֲרוֹמִמְךָ אֱלוֹהַי הַמֶּלֶךְ וַאֲבָרְכָה שִׁמְךָ לְעוֹלָם וָעֶד:\nבְּכָל יוֹם אֲבָרְכֶךָּ וַאֲהַלְלָה שִׁמְךָ לְעוֹלָם וָעֶד:\nגָּדוֹל יהוה וּמְהֻלָּל מְאֹד וְלִגְדֻלָּתוֹ אֵין חֵקֶר:\nדּוֹר לְדוֹר יְשַׁבַּח מַעֲשֶׂיךָ וּגְבוּרֹתֶיךָ יַגִּידוּ:\nהֲדַר כְּבוֹד הוֹדֶךָ וְדִבְרֵי נִפְלְאוֹתֶיךָ אָשִׂיחָה:\nוֶעֱזוּז נוֹרְאֹתֶיךָ יֹאמֵרוּ וּגְדוּלָּתְךָ אֲסַפְּרֶנָּה:\nזֵכֶר רַב טוּבְךָ יַבִּיעוּ וְצִדְקָתְךָ יְרַנֵּנוּ:","cond":[]},{"kind":"text","text":"חַנּוּן וְרַחוּם יהוה אֶרֶךְ אַפַּיִם וּגְדָל חָסֶד:\nטוֹב יהוה לַכֹּל וְרַחֲמָיו עַל כָּל מַעֲשָׂיו:\nיוֹדוּךָ יהוה כָּל מַעֲשֶׂיךָ וַחֲסִידֶיךָ יְבָרְכוּכָה:\nכְּבוֹד מַלְכוּתְךָ יֹאמֵרוּ וּגְבוּרָתְךָ יְדַבֵּרוּ:\nלְהוֹדִיעַ לִבְנֵי הָאָדָם גְּבוּרֹתָיו וּכְבוֹד הֲדַר מַלְכוּתוֹ:\nמַלְכוּתְךָ מַלְכוּת כָּל עֹלָמִים וּמֶמְשַׁלְתְּךָ בְּכָל דּוֹר וָדוֹר:\nסוֹמֵךְ יהוה לְכָל הַנֹּפְלִים וְזוֹקֵף לְכָל הַכְּפוּפִים:\nעֵינֵי כֹל אֵלֶיךָ יְשַׂבֵּרוּ וְאַתָּה נוֹתֵן לָהֶם אֶת אָכְלָם בְּעִתּוֹ:","cond":[]},{"kind":"text","text":"פּוֹתֵחַ אֶת יָדֶךָ וּמַשְׂבִּיעַ לְכָל חַי רָצוֹן:\nצַדִּיק יהוה בְּכָל דְּרָכָיו וְחָסִיד בְּכָל מַעֲשָׂיו:\nקָרוֹב יהוה לְכָל קֹרְאָיו לְכֹל אֲשֶׁר יִקְרָאֻהוּ בֶאֱמֶת:\nרְצוֹן יְרֵאָיו יַעֲשֶׂה וְאֶת שַׁוְעָתָם יִשְׁמַע וְיוֹשִׁיעֵם:\nשׁוֹמֵר יהוה אֶת כָּל אֹהֲבָיו וְאֵת כָּל הָרְשָׁעִים יַשְׁמִיד:\nתְּהִלַּת יהוה יְדַבֶּר פִּי וִיבָרֵךְ כָּל בָּשָׂר שֵׁם קָדְשׁוֹ לְעוֹלָם וָעֶד:\nוַאֲנַחְנוּ נְבָרֵךְ יָהּ מֵעַתָּה וְעַד עוֹלָם הַלְלוּיָהּ:","cond":[]},{"kind":"text","text":"לַמְנַצֵּחַ מִזְמוֹר לְדָוִד: יַעַנְךָ יהוה בְּיוֹם צָרָה, יְשַׂגֶּבְךָ שֵׁם אֱלֹהֵי יַעֲקֹב: יִשְׁלַח עֶזְרְךָ מִקֹּדֶשׁ, וּמִצִּיּוֹן יִסְעָדֶךָּ: יִזְכֹּר כָּל מִנְחֹתֶךָ, וְעוֹלָתְךָ יְדַשְּׁנֶה סֶלָה: יִתֶּן לְךָ כִלְבָבֶךָ, וְכָל עֲצָתְךָ יְמַלֵּא: נְרַנְּנָה בִּישׁוּעָתֶךָ וּבְשֵׁם אֱלֹהֵינוּ נִדְגֹּל, יְמַלֵּא יהוה כָּל מִשְׁאֲלוֹתֶיךָ: עַתָּה יָדַעְתִּי כִּי הוֹשִׁיעַ יהוה מְשִׁיחוֹ, יַעֲנֵהוּ מִשְּׁמֵי קָדְשׁוֹ, בִּגְבֻרוֹת יֵשַׁע יְמִינוֹ: אֵלֶּה בָרֶכֶב וְאֵלֶּה בַסּוּסִים, וַאֲנַחְנוּ בְּשֵׁם יהוה אֱלֹהֵינוּ נַזְכִּיר: הֵמָּה כָּרְעוּ וְנָפָלוּ, וַאֲנַחְנוּ קַּמְנוּ וַנִּתְעוֹדָד: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":["shacharitTachanun"]},{"kind":"instruction","text":"בבית האבל מדלגים על שני הפסוקים הראשונים של \"ובא לציון\", ומתחילים \nמ\"ואתה קדוש\":","cond":[]},{"kind":"text","text":"וּבָא לְצִיּוֹן גּוֹאֵל, וּלְשָׁבֵי פֶשַׁע בְּיַעֲקֹב, נְאֻם יהוה:","cond":["noTishaaBeav"]},{"kind":"text","text":"וַאֲנִי זֹאת בְּרִיתִי אוֹתָם, אָמַר יהוה, רוּחִי אֲשֶׁר עָלֶיךָ וּדְבָרַי אֲשֶׁר שַׂמְתִּי בְּפִיךָ, לֹא יָמוּשׁוּ מִפִּיךָ וּמִפִּי זַרְעֲךָ וּמִפִּי זֶרַע זַרְעֲךָ, אָמַר יהוה, מֵעַתָּה וְעַד עוֹלָם:","cond":["noTishaaBeav"]},{"kind":"header","text":"מגילת אסתר","cond":["megilatEster"]},{"kind":"instruction","text":"הקורא את המגילה מברך לפניה.","cond":["megilatEster"]},{"kind":"text","text":"בָּרוּךְ אַתָּה, יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ עַל מִקְרָא מְגִלָּה.\nבָּרוּךְ אַתָּה, יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁעָשָׂה נִסִּים לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה.","cond":["megilatEster"]},{"kind":"header","text":"פרק א'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק א'","cond":["megilatEster"]},{"kind":"text","text":"וַיְהִי בִּימֵי אֲחַשְׁוֵרוֹשׁ, הוּא אֲחַשְׁוֵרוֹשׁ הַמֹּלֵךְ מֵהֹדּוּ וְעַד כּוּשׁ, שֶׁבַע וְעֶשְׂרִים וּמֵאָה מְדִינָה: בַּיָּמִים הָהֵם, כְּשֶׁבֶת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ עַל כִּסֵּא מַלְכוּתוֹ אֲשֶׁר בְּשׁוּשַׁן הַבִּירָה: בִּשְׁנַת שָׁלוֹשׁ לְמָלְכוֹ עָשָׂה מִשְׁתֶּה לְכָל שָׂרָיו וַעֲבָדָיו, חֵיל פָּרַס וּמָדַי הַפַּרְתְּמִים וְשָׂרֵי הַמְּדִינוֹת לְפָנָיו: בְּהַרְאֹתוֹ אֶת עֹשֶׁר כְּבוֹד מַלְכוּתוֹ וְאֶת יְקָר תִּפְאֶרֶת גְּדוּלָּתוֹ, יָמִים רַבִּים שְׁמוֹנִים וּמְאַת יוֹם: וּבִמְלוֹאת הַיָּמִים הָאֵלֶּה עָשָׂה הַמֶּלֶךְ לְכָל הָעָם הַנִּמְצְאִים בְּשׁוּשַׁן הַבִּירָה לְמִגָּדוֹל וְעַד קָטָן מִשְׁתֶּה שִׁבְעַת יָמִים, בַּחֲצַר גִּנַּת בִּיתַן הַמֶּלֶךְ: חוּר כַּרְפַּס וּתְכֵלֶת אָחוּז בְּחַבְלֵי בוּץ וְאַרְגָּמָן עַל גְּלִילֵי כֶסֶף וְעַמּוּדֵי שֵׁשׁ, מִטּוֹת זָהָב וָכֶסֶף עַל רִצְפַת בַּהַט וָשֵׁשׁ וְדַר וְסֹחָרֶת: וְהַשְׁקוֹת בִּכְלֵי זָהָב וְכֵלִים מִכֵּלִים שׁוֹנִים, וְיֵין מַלְכוּת רָב כְּיַד הַמֶּלֶךְ: וְהַשְּׁתִיָּה כַדָּת אֵין אֹנֵס, כִּי כֵן יִסַּד הַמֶּלֶךְ עַל כָּל רַב בֵּיתוֹ לַעֲשׂוֹת כִּרְצוֹן אִישׁ וָאִישׁ: גַּם וַשְׁתִּי הַמַּלְכָּה עָשְׂתָה מִשְׁתֵּה נָשִׁים, בֵּית הַמַּלְכוּת אֲשֶׁר לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: בַּיּוֹם הַשְּׁבִיעִי כְּטוֹב לֵב הַמֶּלֶךְ בַּיָּיִן, אָמַר לִמְהוּמָן בִּזְּתָא חַרְבוֹנָא בִּגְתָא וַאֲבַגְתָא זֵתַר וְכַרְכַּס שִׁבְעַת הַסָּרִיסִים הַמְשָׁרְתִים אֶת פְּנֵי הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: לְהָבִיא אֶת וַשְׁתִּי הַמַּלְכָּה לִפְנֵי הַמֶּלֶךְ בְּכֶתֶר מַלְכוּת, לְהַרְאוֹת הָעַמִּים וְהַשָּׂרִים אֶת יָפְיָהּ, כִּי טוֹבַת מַרְאֶה הִיא: וַתְּמָאֵן הַמַּלְכָּה וַשְׁתִּי לָבוֹא בִּדְבַר הַמֶּלֶךְ אֲשֶׁר בְּיַד הַסָּרִיסִים, וַיִּקְצֹף הַמֶּלֶךְ מְאֹד וַחֲמָתוֹ בָּעֲרָה בוֹ: וַיֹּאמֶר הַמֶּלֶךְ לַחֲכָמִים יֹדְעֵי הָעִתִּים, כִּי כֵן דְּבַר הַמֶּלֶךְ לִפְנֵי כָּל יֹדְעֵי דָּת וָדִין: וְהַקָּרֹב אֵלָיו כַּרְשְׁנָא שֵׁתָר אַדְמָתָא תַרְשִׁישׁ מֶרֶס מַרְסְנָא מְמוּכָן, שִׁבְעַת שָׂרֵי פָּרַס וּמָדַי רֹאֵי פְּנֵי הַמֶּלֶךְ הַיֹּשְׁבִים רִאשֹׁנָה בַּמַּלְכוּת: כְּדָת מַה לַּעֲשׂוֹת בַּמַּלְכָּה וַשְׁתִּי, עַל אֲשֶׁר לֹא עָשְׂתָה אֶת מַאֲמַר הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ בְּיַד הַסָּרִיסִים: וַיֹּאמֶר מְמוּכָן לִפְנֵי הַמֶּלֶךְ וְהַשָּׂרִים, לֹא עַל הַמֶּלֶךְ לְבַדּוֹ עָוְתָה וַשְׁתִּי הַמַּלְכָּה, כִּי עַל כָּל הַשָּׂרִים וְעַל כָּל הָעַמִּים אֲשֶׁר בְּכָל מְדִינוֹת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: כִּי יֵצֵא דְבַר הַמַּלְכָּה עַל כָּל הַנָּשִׁים לְהַבְזוֹת בַּעְלֵיהֶן בְּעֵינֵיהֶן, בְּאָמְרָם הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ אָמַר לְהָבִיא אֶת וַשְׁתִּי הַמַּלְכָּה לְפָנָיו וְלֹא בָאָה: וְהַיּוֹם הַזֶּה תֹּאמַרְנָה שָׂרוֹת פָּרַס וּמָדַי אֲשֶׁר שָׁמְעוּ אֶת דְּבַר הַמַּלְכָּה לְכֹל שָׂרֵי הַמֶּלֶךְ, וּכְדַי בִּזָּיוֹן וָקָצֶף: אִם עַל הַמֶּלֶךְ טוֹב יֵצֵא דְבַר מַלְכוּת מִלְּפָנָיו וְיִכָּתֵב בְּדָתֵי פָרַס וּמָדַי וְלֹא יַעֲבוֹר, אֲשֶׁר לֹא תָבוֹא וַשְׁתִּי לִפְנֵי הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ וּמַלְכוּתָהּ יִתֵּן הַמֶּלֶךְ לִרְעוּתָהּ הַטּוֹבָה מִמֶּנָּה: וְנִשְׁמַע פִּתְגָם הַמֶּלֶךְ אֲשֶׁר יַעֲשֶׂה בְּכָל מַלְכוּתוֹ כִּי רַבָּה הִיא, וְכָל הַנָּשִׁים יִתְּנוּ יְקָר לְבַעְלֵיהֶן לְמִגָּדוֹל וְעַד קָטָן: וַיִּיטַב הַדָּבָר בְּעֵינֵי הַמֶּלֶךְ וְהַשָּׂרִים, וַיַּעַשׂ הַמֶּלֶךְ כִּדְבַר מְמוּכָן: וַיִּשְׁלַח סְפָרִים אֶל כָּל מְדִינוֹת הַמֶּלֶךְ, אֶל מְדִינָה וּמְדִינָה כִּכְתָבָהּ וְאֶל עַם וָעָם כִּלְשׁוֹנוֹ, לִהְיוֹת כָּל אִישׁ שֹׂרֵר בְּבֵיתוֹ וּמְדַבֵּר כִּלְשׁוֹן עַמּוֹ:","cond":["megilatEster"]},{"kind":"header","text":"פרק ב'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ב'","cond":["megilatEster"]},{"kind":"text","text":"אַחַר הַדְּבָרִים הָאֵלֶּה כְּשֹׁךְ חֲמַת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, זָכַר אֶת וַשְׁתִּי וְאֵת אֲשֶׁר עָשָׂתָה וְאֵת אֲשֶׁר נִגְזַר עָלֶיהָ: וַיֹּאמְרוּ נַעֲרֵי הַמֶּלֶךְ מְשָׁרְתָיו, יְבַקְשׁוּ לַמֶּלֶךְ נְעָרוֹת בְּתוּלוֹת טוֹבוֹת מַרְאֶה: וְיַפְקֵד הַמֶּלֶךְ פְּקִידִים בְּכָל מְדִינוֹת מַלְכוּתוֹ, וְיִקְבְּצוּ אֶת כָּל נַעֲרָה בְתוּלָה טוֹבַת מַרְאֶה אֶל שׁוּשַׁן הַבִּירָה אֶל בֵּית הַנָּשִׁים אֶל יַד הֵגֶא סְרִיס הַמֶּלֶךְ שֹׁמֵר הַנָּשִׁים, וְנָתוֹן תַּמְרוּקֵיהֶן: וְהַנַּעֲרָה אֲשֶׁר תִּיטַב בְּעֵינֵי הַמֶּלֶךְ תִּמְלֹךְ תַּחַת וַשְׁתִּי, וַיִּיטַב הַדָּבָר בְּעֵינֵי הַמֶּלֶךְ וַיַּעַשׂ כֵּן:","cond":["megilatEster"]},{"kind":"special","text":"אִישׁ יְהוּדִי הָיָה בְּשׁוּשַׁן הַבִּירָה, וּשְׁמוֹ מָרְדֳּכַי בֶּן יָאִיר בֶּן שִׁמְעִי בֶּן קִישׁ אִישׁ יְמִינִי:","cond":["megilatEster"]},{"kind":"text","text":"אֲשֶׁר הָגְלָה מִירוּשָׁלַיִם עִם הַגֹּלָה אֲשֶׁר הָגְלְתָה עִם יְכָנְיָה מֶלֶךְ יְהוּדָה, אֲשֶׁר הֶגְלָה נְבוּכַדְנֶאצַּר מֶלֶךְ בָּבֶל: וַיְהִי אֹמֵן אֶת הֲדַסָּה הִיא אֶסְתֵּר בַּת דֹּדוֹ כִּי אֵין לָהּ אָב וָאֵם, וְהַנַּעֲרָה יְפַת תֹּאַר וְטוֹבַת מַרְאֶה וּבְמוֹת אָבִיהָ וְאִמָּהּ לְקָחָהּ מָרְדֳּכַי לוֹ לְבַת: וַיְהִי בְּהִשָּׁמַע דְּבַר הַמֶּלֶךְ וְדָתוֹ, וּבְהִקָּבֵץ נְעָרוֹת רַבּוֹת אֶל שׁוּשַׁן הַבִּירָה אֶל יַד הֵגָי, וַתִּלָּקַח אֶסְתֵּר אֶל בֵּית הַמֶּלֶךְ אֶל יַד הֵגַי שֹׁמֵר הַנָּשִׁים: וַתִּיטַב הַנַּעֲרָה בְעֵינָיו וַתִּשָּׂא חֶסֶד לְפָנָיו, וַיְבַהֵל אֶת תַּמְרוּקֶיהָ וְאֶת מָנוֹתֶהָ לָתֵת לָהּ, וְאֵת שֶׁבַע הַנְּעָרוֹת הָרְאֻיוֹת לָתֶת לָהּ מִבֵּית הַמֶּלֶךְ, וַיְשַׁנֶּהָ וְאֶת נַעֲרוֹתֶיהָ לְטוֹב בֵּית הַנָּשִׁים: לֹא הִגִּידָה אֶסְתֵּר אֶת עַמָּהּ וְאֶת מוֹלַדְתָּהּ, כִּי מָרְדֳּכַי צִוָּה עָלֶיהָ אֲשֶׁר לֹא תַגִּיד: וּבְכָל יוֹם וָיוֹם מָרְדֳּכַי מִתְהַלֵּךְ לִפְנֵי חֲצַר בֵּית הַנָּשִׁים, לָדַעַת אֶת שְׁלוֹם אֶסְתֵּר וּמַה יֵּעָשֶׂה בָּהּ: וּבְהַגִּיעַ תֹּר נַעֲרָה וְנַעֲרָה לָבוֹא אֶל הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, מִקֵּץ הֱיוֹת לָהּ כְּדָת הַנָּשִׁים שְׁנֵים עָשָׂר חֹדֶשׁ כִּי כֵּן יִמְלְאוּ יְמֵי מְרוּקֵיהֶן, שִׁשָּׁה חֳדָשִׁים בְּשֶׁמֶן הַמֹּר וְשִׁשָּׁה חֳדָשִׁים בַּבְּשָׂמִים וּבְתַמְרוּקֵי הַנָּשִׁים: וּבָזֶה הַנַּעֲרָה בָּאָה אֶל הַמֶּלֶךְ, אֵת כָּל אֲשֶׁר תֹּאמַר יִנָּתֵן לָהּ לָבוֹא עִמָּהּ מִבֵּית הַנָּשִׁים עַד בֵּית הַמֶּלֶךְ: בָּעֶרֶב הִיא בָאָה וּבַבֹּקֶר הִיא שָׁבָה אֶל בֵּית הַנָּשִׁים שֵׁנִי, אֶל יַד שַׁעֲשְׁגַז סְרִיס הַמֶּלֶךְ שֹׁמֵר הַפִּילַגְשִׁים, לֹא תָבוֹא עוֹד אֶל הַמֶּלֶךְ כִּי אִם חָפֵץ בָּהּ הַמֶּלֶךְ וְנִקְרְאָה בְשֵׁם: וּבְהַגִּיעַ תֹּר אֶסְתֵּר בַּת אֲבִיחַיִל דֹּד מָרְדֳּכַי אֲשֶׁר לָקַח לוֹ לְבַת לָבוֹא אֶל הַמֶּלֶךְ, לֹא בִקְשָׁה דָּבָר כִּי אִם אֶת אֲשֶׁר יֹאמַר הֵגַי סְרִיס הַמֶּלֶךְ שֹׁמֵר הַנָּשִׁים, וַתְּהִי אֶסְתֵּר נֹשֵׂאת חֵן בְּעֵינֵי כָּל רֹאֶיהָ: וַתִּלָּקַח אֶסְתֵּר אֶל הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ אֶל בֵּית מַלְכוּתוֹ בַּחֹדֶשׁ הָעֲשִׂירִי הוּא חֹדֶשׁ טֵבֵת, בִּשְׁנַת שֶׁבַע לְמַלְכוּתוֹ: וַיֶּאֱהַב הַמֶּלֶךְ אֶת אֶסְתֵּר מִכָּל הַנָּשִׁים וַתִּשָּׂא חֵן וָחֶסֶד לְפָנָיו מִכָּל הַבְּתוּלֹת, וַיָּשֶׂם כֶּתֶר מַלְכוּת בְּרֹאשָׁהּ וַיַּמְלִיכֶהָ תַּחַת וַשְׁתִּי: וַיַּעַשׂ הַמֶּלֶךְ מִשְׁתֶּה גָדוֹל לְכָל שָׂרָיו וַעֲבָדָיו, אֵת מִשְׁתֵּה אֶסְתֵּר, וַהֲנָחָה לַמְּדִינוֹת עָשָׂה וַיִּתֵּן מַשְׂאֵת כְּיַד הַמֶּלֶךְ: וּבְהִקָּבֵץ בְּתוּלוֹת שֵׁנִית, וּמָרְדֳּכַי יֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ: אֵין אֶסְתֵּר מַגֶּדֶת מוֹלַדְתָּהּ וְאֶת עַמָּהּ כַּאֲשֶׁר צִוָּה עָלֶיהָ מָרְדֳּכַי, וְאֶת מַאֲמַר מָרְדֳּכַי אֶסְתֵּר עֹשָׂה כַּאֲשֶׁר הָיְתָה בְאָמְנָה אִתּוֹ: בַּיָּמִים הָהֵם, וּמָרְדֳּכַי יֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ, קָצַף בִּגְתָן וָתֶרֶשׁ שְׁנֵי סָרִיסֵי הַמֶּלֶךְ מִשֹּׁמְרֵי הַסַּף וַיְבַקְשׁוּ לִשְׁלֹחַ יָד בַּמֶּלֶךְ אֲחַשְׁוֵרֹשׁ: וַיִּוָּדַע הַדָּבָר לְמָרְדֳּכַי וַיַּגֵּד לְאֶסְתֵּר הַמַּלְכָּה, וַתֹּאמֶר אֶסְתֵּר לַמֶּלֶךְ בְּשֵׁם מָרְדֳּכַי: וַיְבֻקַּשׁ הַדָּבָר וַיִּמָּצֵא וַיִּתָּלוּ שְׁנֵיהֶם עַל עֵץ, וַיִּכָּתֵב בְּסֵפֶר דִּבְרֵי הַיָּמִים לִפְנֵי הַמֶּלֶךְ:","cond":["megilatEster"]},{"kind":"header","text":"פרק ג'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ג'","cond":["megilatEster"]},{"kind":"text","text":"אַחַר הַדְּבָרִים הָאֵלֶּה גִּדַּל הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ אֶת הָמָן בֶּן הַמְּדָתָא הָאֲגָגִי וַיְנַשְּׂאֵהוּ, וַיָּשֶׂם אֶת כִּסְאוֹ מֵעַל כָּל הַשָּׂרִים אֲשֶׁר אִתּוֹ: וְכָל עַבְדֵי הַמֶּלֶךְ אֲשֶׁר בְּשַׁעַר הַמֶּלֶךְ כֹּרְעִים וּמִשְׁתַּחֲוִים לְהָמָן, כִּי כֵן צִוָּה לוֹ הַמֶּלֶךְ, וּמָרְדֳּכַי לֹא יִכְרַע וְלֹא יִשְׁתַּחֲוֶה: וַיֹּאמְרוּ עַבְדֵי הַמֶּלֶךְ אֲשֶׁר בְּשַׁעַר הַמֶּלֶךְ לְמָרְדֳּכַי, מַדּוּעַ אַתָּה עוֹבֵר אֵת מִצְוַת הַמֶּלֶךְ: וַיְהִי כְּאָמְרָם אֵלָיו יוֹם וָיוֹם וְלֹא שָׁמַע אֲלֵיהֶם, וַיַּגִּידוּ לְהָמָן לִרְאוֹת הֲיַעַמְדוּ דִּבְרֵי מָרְדֳּכַי כִּי הִגִּיד לָהֶם אֲשֶׁר הוּא יְהוּדִי: וַיַּרְא הָמָן כִּי אֵין מָרְדֳּכַי כֹּרֵעַ וּמִשְׁתַּחֲוֶה לוֹ, וַיִּמָּלֵא הָמָן חֵמָה: וַיִּבֶז בְּעֵינָיו לִשְׁלֹח יָד בְּמָרְדֳּכַי לְבַדּוֹ כִּי הִגִּידוּ לוֹ אֶת עַם מָרְדֳּכַי, וַיְבַקֵּשׁ הָמָן לְהַשְׁמִיד אֶת כָּל הַיְּהוּדִים אֲשֶׁר בְּכָל מַלְכוּת אֲחַשְׁוֵרוֹשׁ עַם מָרְדֳּכַי: בַּחֹדֶשׁ הָרִאשׁוֹן הוּא חֹדֶשׁ נִיסָן בִּשְׁנַת שְׁתֵּים עֶשְׂרֵה לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, הִפִּיל פּוּר הוּא הַגּוֹרָל לִפְנֵי הָמָן מִיּוֹם לְיוֹם וּמֵחֹדֶשׁ לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר: וַיֹּאמֶר הָמָן לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ יֶשְׁנוֹ עַם אֶחָד מְפֻזָּר וּמְפֹרָד בֵּין הָעַמִּים בְּכֹל מְדִינוֹת מַלְכוּתֶךָ, וְדָתֵיהֶם שֹׁנוֹת מִכָּל עָם וְאֶת דָּתֵי הַמֶּלֶךְ אֵינָם עֹשִׂים וְלַמֶּלֶךְ אֵין שֹׁוֶה לְהַנִּיחָם: אִם עַל הַמֶּלֶךְ טוֹב יִכָּתֵב לְאַבְּדָם, וַעֲשֶׂרֶת אֲלָפִים כִּכַּר כֶּסֶף אֶשְׁקוֹל עַל יְדֵי עֹשֵׂי הַמְּלָאכָה לְהָבִיא אֶל גִּנְזֵי הַמֶּלֶךְ: וַיָּסַר הַמֶּלֶךְ אֶת טַבַּעְתּוֹ מֵעַל יָדוֹ, וַיִּתְּנָהּ לְהָמָן בֶּן הַמְּדָתָא הָאֲגָגִי צֹרֵר הַיְּהוּדִים: וַיֹּאמֶר הַמֶּלֶךְ לְהָמָן הַכֶּסֶף נָתוּן לָךְ, וְהָעָם לַעֲשׂוֹת בּוֹ כַּטּוֹב בְּעֵינֶיךָ: וַיִּקָּרְאוּ סֹפְרֵי הַמֶּלֶךְ בַּחֹדֶשׁ הָרִאשׁוֹן בִּשְׁלוֹשָׁה עָשָׂר יוֹם בּוֹ, וַיִּכָּתֵב כְּכָל אֲשֶׁר צִוָּה הָמָן אֶל אֲחַשְׁדַּרְפְּנֵי הַמֶּלֶךְ וְאֶל הַפַּחוֹת אֲשֶׁר עַל מְדִינָה וּמְדִינָה וְאֶל שָׂרֵי עַם וָעָם, מְדִינָה וּמְדִינָה כִּכְתָבָהּ וְעַם וָעָם כִּלְשׁוֹנוֹ, בְּשֵׁם הַמֶּלֶךְ אֲחַשְׁוֵרֹשׁ נִכְתָּב וְנֶחְתָּם בְּטַבַּעַת הַמֶּלֶךְ: וְנִשְׁלוֹחַ סְפָרִים בְּיַד הָרָצִים אֶל כָּל מְדִינוֹת הַמֶּלֶךְ, לְהַשְׁמִיד לַהֲרֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלוֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: פַּתְשֶׁגֶן הַכְּתָב לְהִנָּתֵן דָּת בְּכָל מְדִינָה וּמְדִינָה גָּלוּי לְכָל הָעַמִּים, לִהְיוֹת עֲתִדִים לַיּוֹם הַזֶּה: הָרָצִים יָצְאוּ דְחוּפִים בִּדְבַר הַמֶּלֶךְ וְהַדָּת נִתְּנָה בְּשׁוּשַׁן הַבִּירָה, וְהַמֶּלֶךְ וְהָמָן יָשְׁבוּ לִשְׁתּוֹת וְהָעִיר שׁוּשָׁן נָבוֹכָה:","cond":["megilatEster"]},{"kind":"header","text":"פרק ד'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ד'","cond":["megilatEster"]},{"kind":"text","text":"וּמָרְדֳּכַי יָדַע אֶת כָּל אֲשֶׁר נַעֲשָׂה וַיִּקְרַע מָרְדֳּכַי אֶת בְּגָדָיו וַיִּלְבַּשׁ שַׂק וָאֵפֶר, וַיֵּצֵא בְּתוֹךְ הָעִיר וַיִּזְעַק זְעָקָה גְדֹלָה וּמָרָה: וַיָּבוֹא עַד לִפְנֵי שַׁעַר הַמֶּלֶךְ, כִּי אֵין לָבוֹא אֶל שַׁעַר הַמֶּלֶךְ בִּלְבוּשׁ שָׂק: וּבְכָל מְדִינָה וּמְדִינָה מְקוֹם אֲשֶׁר דְּבַר הַמֶּלֶךְ וְדָתוֹ מַגִּיעַ, אֵבֶל גָּדוֹל לַיְּהוּדִים וְצוֹם וּבְכִי וּמִסְפֵּד, שַׂק וָאֵפֶר יֻצַּע לָרַבִּים: וַתָּבוֹאנָה נַעֲרוֹת אֶסְתֵּר וְסָרִיסֶיהָ וַיַּגִּידוּ לָהּ וַתִּתְחַלְחַל הַמַּלְכָּה מְאֹד, וַתִּשְׁלַח בְּגָדִים לְהַלְבִּישׁ אֶת מָרְדֳּכַי וּלְהָסִיר שַׂקּוֹ מֵעָלָיו וְלֹא קִבֵּל: וַתִּקְרָא אֶסְתֵּר לַהֲתָךְ מִסָּרִיסֵי הַמֶּלֶךְ אֲשֶׁר הֶעֱמִיד לְפָנֶיהָ וַתְּצַוֵּהוּ עַל מָרְדֳּכַי, לָדַעַת מַה זֶּה וְעַל מַה זֶּה: וַיֵּצֵא הֲתָךְ אֶל מָרְדֳּכַי, אֶל רְחוֹב הָעִיר אֲשֶׁר לִפְנֵי שַׁעַר הַמֶּלֶךְ: וַיַּגֶּד לוֹ מָרְדֳּכַי אֵת כָּל אֲשֶׁר קָרָהוּ, וְאֵת פָּרָשַׁת הַכֶּסֶף אֲשֶׁר אָמַר הָמָן לִשְׁקוֹל עַל גִּנְזֵי הַמֶּלֶךְ בַּיְּהוּדִים לְאַבְּדָם: וְאֶת פַּתְשֶׁגֶן כְּתָב הַדָּת אֲשֶׁר נִתַּן בְּשׁוּשָׁן לְהַשְׁמִידָם נָתַן לוֹ לְהַרְאוֹת אֶת אֶסְתֵּר וּלְהַגִּיד לָהּ, וּלְצַוּוֹת עָלֶיהָ לָבוֹא אֶל הַמֶּלֶךְ לְהִתְחַנֶּן לוֹ וּלְבַקֵּשׁ מִלְּפָנָיו עַל עַמָּהּ: וַיָּבוֹא הֲתָךְ, וַיַּגֵּד לְאֶסְתֵּר אֵת דִּבְרֵי מָרְדֳּכַי: וַתֹּאמֶר אֶסְתֵּר לַהֲתָךְ, וַתְּצַוֵּהוּ אֶל מָרְדֳּכַי: כָּל עַבְדֵי הַמֶּלֶךְ וְעַם מְדִינוֹת הַמֶּלֶךְ יוֹדְעִים אֲשֶׁר כָּל אִישׁ וְאִשָּׁה אֲשֶׁר יָבוֹא אֶל הַמֶּלֶךְ אֶל הֶחָצֵר הַפְּנִימִית אֲשֶׁר לֹא יִקָּרֵא אַחַת דָּתוֹ לְהָמִית, לְבַד מֵאֲשֶׁר יוֹשִׁיט לוֹ הַמֶּלֶךְ אֶת שַׁרְבִיט הַזָּהָב וְחָיָה, וַאֲנִי לֹא נִקְרֵאתִי לָבוֹא אֶל הַמֶּלֶךְ זֶה שְׁלוֹשִׁים יוֹם: וַיַּגִּידוּ לְמָרְדֳּכַי אֵת דִּבְרֵי אֶסְתֵּר: וַיֹּאמֶר מָרְדֳּכַי לְהָשִׁיב אֶל אֶסְתֵּר, אַל תְּדַמִּי בְנַפְשֵׁךְ לְהִמָּלֵט בֵּית הַמֶּלֶךְ מִכָּל הַיְּהוּדִים: כִּי אִם הַחֲרֵשׁ תַּחֲרִישִׁי בָּעֵת הַזֹּאת, רֶוַח וְהַצָּלָה יַעֲמוֹד לַיְּהוּדִים מִמָּקוֹם אַחֵר וְאַתְּ וּבֵית אָבִיךְ תֹּאבֵדוּ, וּמִי יוֹדֵעַ אִם לְעֵת כָּזֹאת הִגַּעַתְּ לַמַּלְכוּת: וַתֹּאמֶר אֶסְתֵּר לְהָשִׁיב אֶל מָרְדֳּכַי: לֵךְ כְּנוֹס אֶת כָּל הַיְּהוּדִים הַנִּמְצְאִים בְּשׁוּשָׁן וְצוּמוּ עָלַי וְאַל תֹּאכְלוּ וְאַל תִּשְׁתּוּ שְׁלֹשֶׁת יָמִים לַיְלָה וָיוֹם, גַּם אֲנִי וְנַעֲרֹתַי אָצוּם כֵּן, וּבְכֵן אָבוֹא אֶל הַמֶּלֶךְ אֲשֶׁר לֹא כַדָּת וְכַאֲשֶׁר אָבַדְתִּי אָבָדְתִּי: וַיַּעֲבֹר מָרְדֳּכַי, וַיַּעַשׂ כְּכֹל אֲשֶׁר צִוְּתָה עָלָיו אֶסְתֵּר:","cond":["megilatEster"]},{"kind":"header","text":"פרק ה'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ה'","cond":["megilatEster"]},{"kind":"text","text":"וַיְהִי בַּיּוֹם הַשְּׁלִישִׁי וַתִּלְבַּשׁ אֶסְתֵּר מַלְכוּת, וַתַּעֲמֹד בַּחֲצַר בֵּית הַמֶּלֶךְ הַפְּנִימִית נֹכַח בֵּית הַמֶּלֶךְ, וְהַמֶּלֶךְ יוֹשֵׁב עַל כִּסֵּא מַלְכוּתוֹ בְּבֵית הַמַּלְכוּת נֹכַח פֶּתַח הַבָּיִת: וַיְהִי כִרְאוֹת הַמֶּלֶךְ אֶת אֶסְתֵּר הַמַּלְכָּה עֹמֶדֶת בֶּחָצֵר נָשְׂאָה חֵן בְּעֵינָיו, וַיּוֹשֶׁט הַמֶּלֶךְ לְאֶסְתֵּר אֶת שַׁרְבִיט הַזָּהָב אֲשֶׁר בְּיָדוֹ, וַתִּקְרַב אֶסְתֵּר וַתִּגַּע בְּרֹאשׁ הַשַּׁרְבִיט: וַיֹּאמֶר לָהּ הַמֶּלֶךְ מַה לָּךְ אֶסְתֵּר הַמַּלְכָּה, וּמַה בַּקָּשָׁתֵךְ עַד חֲצִי הַמַּלְכוּת וְיִנָּתֵן לָךְ: וַתֹּאמֶר אֶסְתֵּר אִם עַל הַמֶּלֶךְ טוֹב, יָבוֹא הַמֶּלֶךְ וְהָמָן הַיּוֹם אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשִׂיתִי לוֹ: וַיֹּאמֶר הַמֶּלֶךְ מַהֲרוּ אֶת הָמָן לַעֲשׂוֹת אֶת דְּבַר אֶסְתֵּר, וַיָּבֹא הַמֶּלֶךְ וְהָמָן אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשְׂתָה אֶסְתֵּר: וַיֹּאמֶר הַמֶּלֶךְ לְאֶסְתֵּר בְּמִשְׁתֵּה הַיַּיִן מַה שְּׁאֵלָתֵךְ וְיִנָּתֵן לָךְ, וּמַה בַּקָּשָׁתֵךְ עַד חֲצִי הַמַּלְכוּת וְתֵעָשׂ: וַתַּעַן אֶסְתֵּר וַתֹּאמַר, שְׁאֵלָתִי וּבַקָּשָׁתִי: אִם מָצָאתִי חֵן בְּעֵינֵי הַמֶּלֶךְ וְאִם עַל הַמֶּלֶךְ טוֹב לָתֵת אֶת שְׁאֵלָתִי וְלַעֲשׂוֹת אֶת בַּקָּשָׁתִי, יָבוֹא הַמֶּלֶךְ וְהָמָן אֶל הַמִּשְׁתֶּה אֲשֶׁר אֶעֱשֶׂה לָהֶם וּמָחָר אֶעֱשֶׂה כִּדְבַר הַמֶּלֶךְ: וַיֵּצֵא הָמָן בַּיּוֹם הַהוּא שָׂמֵחַ וְטוֹב לֵב, וְכִרְאוֹת הָמָן אֶת מָרְדֳּכַי בְּשַׁעַר הַמֶּלֶךְ וְלֹא קָם וְלֹא זָע מִמֶּנּוּ וַיִּמָּלֵא הָמָן עַל מָרְדֳּכַי חֵמָה: וַיִּתְאַפַּק הָמָן וַיָּבוֹא אֶל בֵּיתוֹ, וַיִּשְׁלַח וַיָּבֵא אֶת אֹהֲבָיו וְאֶת זֶרֶשׁ אִשְׁתּוֹ: וַיְסַפֵּר לָהֶם הָמָן אֶת כְּבוֹד עָשְׁרוֹ וְרֹב בָּנָיו, וְאֵת כָּל אֲשֶׁר גִּדְּלוֹ הַמֶּלֶךְ וְאֵת אֲשֶׁר נִשְּׂאוֹ עַל הַשָּׂרִים וְעַבְדֵי הַמֶּלֶךְ: וַיֹּאמֶר הָמָן, אַף לֹא הֵבִיאָה אֶסְתֵּר הַמַּלְכָּה עִם הַמֶּלֶךְ אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשָׂתָה כִּי אִם אוֹתִי, וְגַם לְמָחָר אֲנִי קָרוּא לָהּ עִם הַמֶּלֶךְ: וְכָל זֶה אֵינֶנּוּ שֹׁוֶה לִי, בְּכָל עֵת אֲשֶׁר אֲנִי רֹאֶה אֶת מָרְדֳּכַי הַיְּהוּדִי יוֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ: וַתֹּאמֶר לוֹ זֶרֶשׁ אִשְׁתּוֹ וְכָל אֹהֲבָיו יַעֲשׂוּ עֵץ גָּבֹהַּ חֲמִשִּׁים אַמָּה, וּבַבֹּקֶר אֱמֹר לַמֶּלֶךְ וְיִתְלוּ אֶת מָרְדֳּכַי עָלָיו וּבֹא עִם הַמֶּלֶךְ אֶל הַמִּשְׁתֶּה שָׂמֵחַ, וַיִּיטַב הַדָּבָר לִפְנֵי הָמָן וַיַּעַשׂ הָעֵץ:","cond":["megilatEster"]},{"kind":"header","text":"פרק ו'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ו'","cond":["megilatEster"]},{"kind":"special","text":"בַּלַּיְלָה הַהוּא נָדְדָה שְׁנַת הַמֶּלֶךְ, וַיֹּאמֶר לְהָבִיא אֶת סֵפֶר הַזִּכְרֹנוֹת דִּבְרֵי הַיָּמִים, וַיִּהְיוּ נִקְרָאִים לִפְנֵי הַמֶּלֶךְ:","cond":["megilatEster"]},{"kind":"text","text":"וַיִּמָּצֵא כָתוּב אֲשֶׁר הִגִּיד מָרְדֳּכַי עַל בִּגְתָנָא וָתֶרֶשׁ שְׁנֵי סָרִיסֵי הַמֶּלֶךְ מִשֹּׁמְרֵי הַסַּף אֲשֶׁר בִּקְשׁוּ לִשְׁלֹחַ יָד בַּמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: וַיֹּאמֶר הַמֶּלֶךְ מַה נַּעֲשָׂה יְקָר וּגְדוּלָּה לְמָרְדֳּכַי עַל זֶה, וַיֹּאמְרוּ נַעֲרֵי הַמֶּלֶךְ מְשָׁרְתָיו לֹא נַעֲשָׂה עִמּוֹ דָּבָר: וַיֹּאמֶר הַמֶּלֶךְ מִי בֶחָצֵר, וְהָמָן בָּא לַחֲצַר בֵּית הַמֶּלֶךְ הַחִיצוֹנָה לֵאמֹר לַמֶּלֶךְ לִתְלוֹת אֶת מָרְדֳּכַי עַל הָעֵץ אֲשֶׁר הֵכִין לוֹ: וַיֹּאמְרוּ נַעֲרֵי הַמֶּלֶךְ אֵלָיו הִנֵּה הָמָן עֹמֵד בֶּחָצֵר, וַיֹּאמֶר הַמֶּלֶךְ יָבוֹא: וַיָּבוֹא הָמָן, וַיֹּאמֶר לוֹ הַמֶּלֶךְ מַה לַעֲשׂוֹת בָּאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ, וַיֹּאמֶר הָמָן בְּלִבּוֹ לְמִי יַחְפֹּץ הַמֶּלֶךְ לַעֲשׂוֹת יְקָר יוֹתֵר מִמֶּנִּי: וַיֹּאמֶר הָמָן אֶל הַמֶּלֶךְ, אִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ: יָבִיאוּ לְבוּשׁ מַלְכוּת אֲשֶׁר לָבַשׁ בּוֹ הַמֶּלֶךְ, וְסוּס אֲשֶׁר רָכַב עָלָיו הַמֶּלֶךְ וַאֲשֶׁר נִתַּן כֶּתֶר מַלְכוּת בְּרֹאשׁוֹ: וְנָתוֹן הַלְּבוּשׁ וְהַסּוּס עַל יַד אִישׁ מִשָּׂרֵי הַמֶּלֶךְ הַפַּרְתְּמִים וְהִלְבִּישׁוּ אֶת הָאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ, וְהִרְכִּיבֻהוּ עַל הַסּוּס בִּרְחוֹב הָעִיר וְקָרְאוּ לְפָנָיו כָּכָה יֵעָשֶׂה לָאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ: וַיֹּאמֶר הַמֶּלֶךְ לְהָמָן מַהֵר קַח אֶת הַלְּבוּשׁ וְאֶת הַסּוּס כַּאֲשֶׁר דִּבַּרְתָּ וַעֲשֵׂה כֵן לְמָרְדֳּכַי הַיְּהוּדִי הַיּוֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ, אַל תַּפֵּל דָּבָר מִכֹּל אֲשֶׁר דִּבַּרְתָּ: וַיִּקַּח הָמָן אֶת הַלְּבוּשׁ וְאֶת הַסּוּס וַיַּלְבֵּשׁ אֶת מָרְדֳּכַי, וַיַּרְכִּיבֵהוּ בִּרְחוֹב הָעִיר וַיִּקְרָא לְפָנָיו כָּכָה יֵעָשֶׂה לָאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ: וַיָּשָָב מָרְדֳּכַי אֶל שַׁעַר הַמֶּלֶךְ, וְהָמָן נִדְחַף אֶל בֵּיתוֹ אָבֵל וַחֲפוּי רֹאשׁ: וַיְסַפֵּר הָמָן לְזֶרֶשׁ אִשְׁתּוֹ וּלְכָל אֹהֲבָיו אֵת כָּל אֲשֶׁר קָרָהוּ, וַיֹּאמְרוּ לּוֹ חֲכָמָיו וְזֶרֶשׁ אִשְׁתּוֹ אִם מִזֶּרַע הַיְּהוּדִים מָרְדֳּכַי אֲשֶׁר הַחִלּוֹתָ לִנְפֹּל לְפָנָיו לֹא תוּכַל לוֹ, כִּי נָפוֹל תִּפּוֹל לְפָנָיו: עוֹדָם מְדַבְּרִים עִמּוֹ וְסָרִיסֵי הַמֶּלֶךְ הִגִּיעוּ, וַיַּבְהִלוּ לְהָבִיא אֶת הָמָן אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשְׂתָה אֶסְתֵּר:","cond":["megilatEster"]},{"kind":"header","text":"פרק ז'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ז'","cond":["megilatEster"]},{"kind":"text","text":"וַיָּבֹא הַמֶּלֶךְ וְהָמָן לִשְׁתּוֹת עִם אֶסְתֵּר הַמַּלְכָּה: וַיֹּאמֶר הַמֶּלֶךְ לְאֶסְתֵּר גַּם בַּיּוֹם הַשֵּׁנִי בְּמִשְׁתֵּה הַיַּיִן מַה שְּׁאֵלָתֵךְ אֶסְתֵּר הַמַּלְכָּה וְתִנָּתֵן לָךְ, וּמַה בַּקָּשָׁתֵךְ עַד חֲצִי הַמַּלְכוּת וְתֵעָשׂ: וַתַּעַן אֶסְתֵּר הַמַּלְכָּה וַתֹּאמַר אִם מָצָאתִי חֵן בְּעֵינֶיךָ הַמֶּלֶךְ וְאִם עַל הַמֶּלֶךְ טוֹב, תִּנָּתֶן לִי נַפְשִׁי בִּשְׁאֵלָתִי וְעַמִּי בְּבַקָּשָׁתִי: כִּי נִמְכַּרְנוּ אֲנִי וְעַמִּי לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד, וְאִלּוּ לַעֲבָדִים וְלִשְׁפָחוֹת נִמְכַּרְנוּ הֶחֱרַשְׁתִּי כִּי אֵין הַצָּר שֹׁוֶה בְּנֵזֶק הַמֶּלֶךְ: וַיֹּאמֶר הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ וַיֹּאמֶר לְאֶסְתֵּר הַמַּלְכָּה, מִי הוּא זֶה וְאֵי זֶה הוּא אֲשֶׁר מְלָאוֹ לִבּוֹ לַעֲשׂוֹת כֵּן: וַתֹּאמֶר אֶסְתֵּר אִישׁ צַר וְאוֹיֵב הָמָן הָרָע הַזֶּה, וְהָמָן נִבְעַת מִלִּפְנֵי הַמֶּלֶךְ וְהַמַּלְכָּה: וְהַמֶּלֶךְ קָם בַּחֲמָתוֹ מִמִּשְׁתֵּה הַיַּיִן אֶל גִּנַּת הַבִּיתָן, וְהָמָן עָמַד לְבַקֵּשׁ עַל נַפְשׁוֹ מֵאֶסְתֵּר הַמַּלְכָּה כִּי רָאָה כִּי כָלְתָה אֵלָיו הָרָעָה מֵאֵת הַמֶּלֶךְ: וְהַמֶּלֶךְ שָׁב מִגִּנַּת הַבִּיתָן אֶל בֵּית מִשְׁתֵּה הַיַּיִן וְהָמָן נֹפֵל עַל הַמִּטָּה אֲשֶׁר אֶסְתֵּר עָלֶיהָ, וַיֹּאמֶר הַמֶּלֶךְ הֲגַם לִכְבּוֹשׁ אֶת הַמַּלְכָּה עִמִּי בַּבָּיִת, הַדָּבָר יָצָא מִפִּי הַמֶּלֶךְ וּפְנֵי הָמָן חָפוּ: וַיֹּאמֶר חַרְבוֹנָה אֶחָד מִן הַסָּרִיסִים לִפְנֵי הַמֶּלֶךְ גַּם הִנֵּה הָעֵץ אֲשֶׁר עָשָׂה הָמָן לְמָרְדֳּכַי אֲשֶׁר דִּבֶּר טוֹב עַל הַמֶּלֶךְ עֹמֵד בְּבֵית הָמָן גָּבֹהַּ חֲמִשִּׁים אַמָּה, וַיֹּאמֶר הַמֶּלֶךְ תְּלֻהוּ עָלָיו: וַיִּתְלוּ אֶת הָמָן עַל הָעֵץ אֲשֶׁר הֵכִין לְמָרְדֳּכַי, וַחֲמַת הַמֶּלֶךְ שָׁכָכָה:","cond":["megilatEster"]},{"kind":"header","text":"פרק ח'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ח'","cond":["megilatEster"]},{"kind":"text","text":"בַּיּוֹם הַהוּא נָתַן הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ לְאֶסְתֵּר הַמַּלְכָּה אֶת בֵּית הָמָן צֹרֵר הַיְּהוּדִים, וּמָרְדֳּכַי בָּא לִפְנֵי הַמֶּלֶךְ כִּי הִגִּידָה אֶסְתֵּר מַה הוּא לָהּ: וַיָּסַר הַמֶּלֶךְ אֶת טַבַּעְתּוֹ אֲשֶׁר הֶעֱבִיר מֵהָמָן וַיִּתְּנָהּ לְמָרְדֳּכַי, וַתָּשֶׂם אֶסְתֵּר אֶת מָרְדֳּכַי עַל בֵּית הָמָן: וַתּוֹסֶף אֶסְתֵּר וַתְּדַבֵּר לִפְנֵי הַמֶּלֶךְ וַתִּפֹּל לִפְנֵי רַגְלָיו, וַתֵּבְךְּ וַתִּתְחַנֶּן לוֹ לְהַעֲבִיר אֶת רָעַת הָמָן הָאֲגָגִי וְאֵת מַחֲשַׁבְתּוֹ אֲשֶׁר חָשַׁב עַל הַיְּהוּדִים: וַיּוֹשֶׁט הַמֶּלֶךְ לְאֶסְתֵּר אֵת שַׁרְבִט הַזָּהָב, וַתָּקָם אֶסְתֵּר וַתַּעֲמֹד לִפְנֵי הַמֶּלֶךְ: וַתֹּאמֶר אִם עַל הַמֶּלֶךְ טוֹב וְאִם מָצָאתִי חֵן לְפָנָיו וְכָשֵׁר הַדָּבָר לִפְנֵי הַמֶּלֶךְ וְטוֹבָה אֲנִי בְּעֵינָיו, יִכָּתֵב לְהָשִׁיב אֶת הַסְּפָרִים מַחֲשֶׁבֶת הָמָן בֶּן הַמְּדָתָא הָאֲגָגִי אֲשֶׁר כָּתַב לְאַבֵּד אֶת הַיְּהוּדִים אֲשֶׁר בְּכָל מְדִינוֹת הַמֶּלֶךְ: כִּי אֵיכָכָה אוּכַל וְרָאִיתִי בָּרָעָה אֲשֶׁר יִמְצָא אֶת עַמִּי, וְאֵיכָכָה אוּכַל וְרָאִיתִי בְּאָבְדַן מוֹלַדְתִּי: וַיֹּאמֶר הַמֶּלֶךְ אֲחַשְׁוֵרֹשׁ לְאֶסְתֵּר הַמַּלְכָּה וּלְמָרְדֳּכַי הַיְּהוּדִי, הִנֵּה בֵית הָמָן נָתַתִּי לְאֶסְתֵּר וְאֹתוֹ תָּלוּ עַל הָעֵץ עַל אֲשֶׁר שָׁלַח יָדוֹ בַּיְּהוּדִים: וְאַתֶּם כִּתְבוּ עַל הַיְּהוּדִים כַּטּוֹב בְּעֵינֵיכֶם בְּשֵׁם הַמֶּלֶךְ וְחִתְמוּ בְּטַבַּעַת הַמֶּלֶךְ, כִּי כְתָב אֲשֶׁר נִכְתָּב בְּשֵׁם הַמֶּלֶךְ וְנַחְתּוֹם בְּטַבַּעַת הַמֶּלֶךְ אֵין לְהָשִׁיב: וַיִּקָּרְאוּ סֹפְרֵי הַמֶּלֶךְ בָּעֵת הַהִיא בַּחֹדֶשׁ הַשְּׁלִישִׁי הוּא חֹדֶשׁ סִיוָן בִּשְׁלוֹשָׁה וְעֶשְׂרִים בּוֹ, וַיִּכָּתֵב כְּכָל אֲשֶׁר צִוָּה מָרְדֳּכַי אֶל הַיְּהוּדִים וְאֶל הָאֲחַשְׁדַּרְפְּנִים וְהַפַּחוֹת וְשָׂרֵי הַמְּדִינוֹת אֲשֶׁר מֵהֹדּוּ וְעַד כּוּשׁ, שֶׁבַע וְעֶשְׂרִים וּמֵאָה מְדִינָה, מְדִינָה וּמְדִינָה כִּכְתָבָהּ וְעַם וָעָם כִּלְשֹׁנוֹ, וְאֶל הַיְּהוּדִים כִּכְתָבָם וְכִלְשׁוֹנָם: וַיִּכְתֹּב בְּשֵׁם הַמֶּלֶךְ אֲחַשְׁוֵרֹשׁ וַיַּחְתֹּם בְּטַבַּעַת הַמֶּלֶךְ, וַיִּשְׁלַח סְפָרִים בְּיַד הָרָצִים בַּסּוּסִים רֹכְבֵי הָרֶכֶשׁ הָאֲחַשְׁתְּרָנִים בְּנֵי הָרַמָּכִים: אֲשֶׁר נָתַן הַמֶּלֶךְ לַיְּהוּדִים אֲשֶׁר בְּכָל עִיר וָעִיר לְהִקָּהֵל וְלַעֲמֹד עַל נַפְשָׁם, לְהַשְׁמִיד וְלַהֲרֹג וּלְאַבֵּד אֶת כָּל חֵיל עַם וּמְדִינָה הַצָּרִים אֹתָם טַף וְנָשִׁים, וּשְׁלָלָם לָבוֹז: בְּיוֹם אֶחָד בְּכָל מְדִינוֹת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, בִּשְׁלוֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר: פַּתְשֶׁגֶן הַכְּתָב לְהִנָּתֵן דָּת בְּכָל מְדִינָה וּמְדִינָה גָּלוּי לְכָל הָעַמִּים, וְלִהְיוֹת הַיְּהוּדִים עֲתִידִים לַיּוֹם הַזֶּה לְהִנָּקֵם מֵאֹיְבֵיהֶם: הָרָצִים רֹכְבֵי הָרֶכֶשׁ הָאֲחַשְׁתְּרָנִים יָצְאוּ מְבֹהָלִים וּדְחוּפִים בִּדְבַר הַמֶּלֶךְ, וְהַדָּת נִתְּנָה בְּשׁוּשַׁן הַבִּירָה:","cond":["megilatEster"]},{"kind":"special","text":"וּמָרְדֳּכַי יָצָא מִלִּפְנֵי הַמֶּלֶךְ בִּלְבוּשׁ מַלְכוּת תְּכֵלֶת וָחוּר וַעֲטֶרֶת זָהָב גְּדוֹלָה וְתַכְרִיךְ בּוּץ וְאַרְגָּמָן, וְהָעִיר שׁוּשָׁן צָהֲלָה וְשָׂמֵחָה: לַיְּהוּדִים הָיְתָה אוֹרָה וְשִׂמְחָה, וְשָׂשֹׂן וִיקָר:","cond":["megilatEster"]},{"kind":"text","text":"וּבְכָל מְדִינָה וּמְדִינָה וּבְכָל עִיר וָעִיר, מְקוֹם אֲשֶׁר דְּבַר הַמֶּלֶךְ וְדָתוֹ מַגִּיעַ, שִׂמְחָה וְשָׂשׂוֹן לַיְּהוּדִים מִשְׁתֶּה וְיוֹם טוֹב, וְרַבִּים מֵעַמֵּי הָאָרֶץ מִתְיַהֲדִים כִּי נָפַל פַּחַד הַיְּהוּדִים עֲלֵיהֶם:","cond":["megilatEster"]},{"kind":"header","text":"פרק ט'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ט'","cond":["megilatEster"]},{"kind":"text","text":"וּבִשְׁנֵים עָשָׂר חֹדֶשׁ הוּא חֹדֶשׁ אֲדָר בִּשְׁלוֹשָׁה עָשָׂר יוֹם בּוֹ אֲשֶׁר הִגִּיעַ דְּבַר הַמֶּלֶךְ וְדָתוֹ לְהֵעָשׂוֹת, בַּיּוֹם אֲשֶׁר שִׂבְּרוּ אֹיְבֵי הַיְּהוּדִים לִשְׁלוֹט בָּהֶם וְנַהֲפוֹךְ הוּא אֲשֶׁר יִשְׁלְטוּ הַיְּהוּדִים הֵמָּה בְּשֹׂנְאֵיהֶם: נִקְהֲלוּ הַיְּהוּדִים בְּעָרֵיהֶם בְּכָל מְדִינוֹת הַמֶּלֶךְ אֳחַשְׁוֵרוֹשׁ לִשְׁלֹחַ יָד בִּמְבַקְשֵׁי רָעָתָם, וְאִישׁ לֹא עָמַד לִפְנֵיהֶם כִּי נָפַל פַּחְדָּם עַל כָּל הָעַמִּים: וְכָל שָׂרֵי הַמְּדִינוֹת וְהָאֲחַשְׁדַּרְפְּנִים וְהַפַּחוֹת וְעֹשֵׂי הַמְּלָאכָה אֲשֶׁר לַמֶּלֶךְ מְנַשְּׂאִים אֶת הַיְּהוּדִים, כִּי נָפַל פַּחַד מָרְדֳּכַי עֲלֵיהֶם: כִּי גָדוֹל מָרְדֳּכַי בְּבֵית הַמֶּלֶךְ וְשָׁמְעוֹ הוֹלֵךְ בְּכָל הַמְּדִינוֹת, כִּי הָאִישׁ מָרְדֳּכַי הוֹלֵךְ וְגָדוֹל: וַיַּכּוּ הַיְּהוּדִים בְּכָל אֹיְבֵיהֶם מַכַּת חֶרֶב וְהֶרֶג וְאַבְדָן, וַיַּעֲשׂוּ בְשֹׂנְאֵיהֶם כִּרְצוֹנָם: וּבְשׁוּשַׁן הַבִּירָה הָרְגוּ הַיְּהוּדִים וְאַבֵּד חֲמֵשׁ מֵאוֹת אִישׁ: וְאֵת פַּרְשַׁנְדָּתָא וְאֵת דַּלְפוֹן וְאֵת אַסְפָּתָא: וְאֵת פּוֹרָתָא וְאֵת אֲדַלְיָא וְאֵת אֲרִידָתָא: וְאֵת פַּרְמַשְׁתָּא וְאֵת אֲרִיסַי וְאֵת אֲרִדַי וְאֵת וַיְזָתָא: עֲשֶׂרֶת בְּנֵי הָמָן בֶּן הַמְּדָתָא צֹרֵר הַיְּהוּדִים הָרָגוּ, וּבַבִּזָּה לֹא שָׁלְחוּ אֶת יָדָם: בַּיּוֹם הַהוּא בָּא מִסְפַּר הַהֲרוּגִים בְּשׁוּשַׁן הַבִּירָה לִפְנֵי הַמֶּלֶךְ: וַיֹּאמֶר הַמֶּלֶךְ לְאֶסְתֵּר הַמַּלְכָּה בְּשׁוּשַׁן הַבִּירָה הָרְגוּ הַיְּהוּדִים וְאַבֵּד חֲמֵשׁ מֵאוֹת אִישׁ וְאֵת עֲשֶׂרֶת בְּנֵי הָמָן, בִּשְׁאָר מְדִינוֹת הַמֶּלֶךְ מֶה עָשׂוּ, וּמַה שְּׁאֵלָתֵךְ וְיִנָּתֵן לָךְ וּמַה בַּקָּשָׁתֵךְ עוֹד וְתֵעָשׂ: וַתֹּאמֶר אֶסְתֵּר אִם עַל הַמֶּלֶךְ טוֹב, יִנָּתֵן גַּם מָחָר לַיְּהוּדִים אֲשֶׁר בְּשׁוּשָׁן לַעֲשׂוֹת כְּדָת הַיּוֹם, וְאֵת עֲשֶׂרֶת בְּנֵי הָמָן יִתְלוּ עַל הָעֵץ: וַיֹּאמֶר הַמֶּלֶךְ לְהֵעָשׂוֹת כֵּן וַתִּנָּתֵן דָּת בְּשׁוּשָׁן, וְאֵת עֲשֶׂרֶת בְּנֵי הָמָן תָּלוּ: וַיִּקָּהֲלוּ הַיְּהוּדִים אֲשֶׁר בְּשׁוּשָׁן גַּם בְּיוֹם אַרְבָּעָה עָשָׂר לְחֹדֶשׁ אֲדָר וַיַּהַרְגוּ בְשׁוּשָׁן שְׁלֹשׁ מֵאוֹת אִישׁ, וּבַבִּזָּה לֹא שָׁלְחוּ אֶת יָדָם: וּשְׁאָר הַיְּהוּדִים אֲשֶׁר בִּמְדִינוֹת הַמֶּלֶךְ נִקְהֲלוּ וְעָמֹד עַל נַפְשָׁם וְנוֹחַ מֵאֹיְבֵיהֶם וְהָרֹג בְּשֹׂנְאֵיהֶם חֲמִשָּׁה וְשִׁבְעִים אָלֶף, וּבַבִּזָּה לֹא שָׁלְחוּ אֶת יָדָם: בְּיוֹם שְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ אֲדָר, וְנוֹחַ בְּאַרְבָּעָה עָשָׂר בּוֹ וְעָשֹׂה אֹתוֹ יוֹם מִשְׁתֶּה וְשִׂמְחָה: וְהַיְּהוּדִים אֲשֶׁר בְּשׁוּשָׁן נִקְהֲלוּ בִּשְׁלֹשָׁה עָשָׂר בּוֹ וּבְאַרְבָּעָה עָשָׂר בּוֹ, וְנוֹחַ בַּחֲמִשָּׁה עָשָׂר בּוֹ וְעָשֹׂה אֹתוֹ יוֹם מִשְׁתֶּה וְשִׂמְחָה: עַל כֵּן הַיְּהוּדִים הַפְּרָזִים הַיֹּשְׁבִים בְּעָרֵי הַפְּרָזוֹת, עֹשִׂים אֵת יוֹם אַרְבָּעָה עָשָׂר לְחֹדֶשׁ אֲדָר שִׂמְחָה וּמִשְׁתֶּה וְיוֹם טוֹב, וּמִשְׁלוֹחַ מָנוֹת אִישׁ לְרֵעֵהוּ: וַיִּכְתֹּב מָרְדֳּכַי אֶת הַדְּבָרִים הָאֵלֶּה, וַיִּשְׁלַח סְפָרִים אֶל כָּל הַיְּהוּדִים אֲשֶׁר בְּכָל מְדִינוֹת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ הַקְּרוֹבִים וְהָרְחוֹקִים: לְקַיֵּם עֲלֵיהֶם, לִהְיוֹת עֹשִׂים אֵת יוֹם אַרְבָּעָה עָשָׂר לְחֹדֶשׁ אֲדָר וְאֵת יוֹם חֲמִשָּׁה עָשָׂר בּוֹ, בְּכָל שָׁנָה וְשָׁנָה: כַּיָּמִים אֲשֶׁר נָחוּ בָהֶם הַיְּהוּדִים מֵאוֹיְבֵיהֶם, וְהַחֹדֶשׁ אֲשֶׁר נֶהְפַּךְ לָהֶם מִיָּגוֹן לְשִׂמְחָה וּמֵאֵבֶל לְיוֹם טוֹב, לַעֲשׂוֹת אוֹתָם יְמֵי מִשְׁתֶּה וְשִׂמְחָה וּמִשְׁלוֹחַ מָנוֹת אִישׁ לְרֵעֵהוּ וּמַתָּנוֹת לָאֶבְיוֹנִים: וְקִבֵּל הַיְּהוּדִים אֵת אֲשֶׁר הֵחֵלּוּ לַעֲשׂוֹת, וְאֵת אֲשֶׁר כָּתַב מָרְדֳּכַי אֲלֵיהֶם: כִּי הָמָן בֶּן הַמְּדָתָא הָאֲגָגִי צֹרֵר כָּל הַיְּהוּדִים חָשַׁב עַל הַיְּהוּדִים לְאַבְּדָם, וְהִפִּיל פּוּר הוּא הַגּוֹרָל לְהֻמָּם וּלְאַבְּדָם: וּבְבֹאָהּ לִפְנֵי הַמֶּלֶךְ, אָמַר עִם הַסֵּפֶר יָשׁוּב מַחֲשַׁבְתּוֹ הָרָעָה אֲשֶׁר חָשַׁב עַל הַיְּהוּדִים עַל רֹאשׁוֹ, וְתָלוּ אֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ: עַל כֵּן קָרְאוּ לַיָּמִים הָאֵלֶּה פוּרִים עַל שֵׁם הַפּוּר, עַל כֵּן עַל כָּל דִּבְרֵי הָאִגֶּרֶת הַזֹּאת, וּמָה רָאוּ עַל כָּכָה וּמָה הִגִּיעַ אֲלֵיהֶם: קִיְּמוּ וְקִבְּלוּ הַיְּהוּדִים עֲלֵיהֶם וְעַל זַרְעָם וְעַל כָּל הַנִּלְוִים עֲלֵיהֶם וְלֹא יַעֲבוֹר, לִהְיוֹת עֹשִׂים אֵת שְׁנֵי הַיָּמִים הָאֵלֶּה כִּכְתָבָם וְכִזְמַנָּם, בְּכָל שָׁנָה וְשָׁנָה: וְהַיָּמִים הָאֵלֶּה נִזְכָּרִים וְנַעֲשִׂים בְּכָל דּוֹר וָדוֹר מִשְׁפָּחָה וּמִשְׁפָּחָה מְדִינָה וּמְדִינָה וְעִיר וָעִיר, וִימֵי הַפּוּרִים הָאֵלֶּה לֹא יַעַבְרוּ מִתּוֹךְ הַיְּהוּדִים וְזִכְרָם לֹא יָסוּף מִזַּרְעָם: וַתִּכְתֹּב אֶסְתֵּר הַמַּלְכָּה בַת אֲבִיחַיִל וּמָרְדֳּכַי הַיְּהוּדִי אֶת כָּל תֹּקֶף, לְקַיֵּם אֵת אִגֶּרֶת הַפּוּרִים הַזֹּאת הַשֵּׁנִית: וַיִּשְׁלַח סְפָרִים אֶל כָּל הַיְּהוּדִים, אֶל שֶׁבַע וְעֶשְׂרִים וּמֵאָה מְדִינָה מַלְכוּת אֲחַשְׁוֵרוֹשׁ, דִּבְרֵי שָׁלוֹם וֶאֱמֶת: לְקַיֵּם אֵת יְמֵי הַפֻּרִים הָאֵלֶּה בִּזְמַנֵּיהֶם כַּאֲשֶׁר קִיַּם עֲלֵיהֶם מָרְדֳּכַי הַיְּהוּדִי וְאֶסְתֵּר הַמַּלְכָּה וְכַאֲשֶׁר קִיְּמוּ עַל נַפְשָׁם וְעַל זַרְעָם, דִּבְרֵי הַצֹּמוֹת וְזַעֲקָתָם: וּמַאֲמַר אֶסְתֵּר קִיַּם דִּבְרֵי הַפֻּרִים הָאֵלֶּה, וְנִכְתָּב בַּסֵּפֶר:","cond":["megilatEster"]},{"kind":"header","text":"פרק י'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק י'","cond":["megilatEster"]},{"kind":"text","text":"וַיָּשֶׂם הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ מַס עַל הָאָרֶץ וְאִיֵּי הַיָּם: וְכָל מַעֲשֵׂה תָקְפּוֹ וּגְבוּרָתוֹ, וּפָרָשַׁת גְּדֻלַּת מָרְדֳּכַי אֲשֶׁר גִּדְּלוֹ הַמֶּלֶךְ, הֲלוֹא הֵם כְּתוּבִים עַל סֵפֶר דִּבְרֵי הַיָּמִים לְמַלְכֵי מָדַי וּפָרָס:","cond":["megilatEster"]},{"kind":"special","text":"כִּי מָרְדֳּכַי הַיְּהוּדִי מִשְׁנֶה לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ וְגָדוֹל לַיְּהוּדִים וְרָצוּי לְרֹב אֶחָיו, דֹּרֵשׁ טוֹב לְעַמּוֹ וְדֹבֵר שָׁלוֹם לְכָל זַרְעוֹ:","cond":["megilatEster"]},{"kind":"header","text":"ברכת הרב את ריבנו","cond":["megilatEster"]},{"kind":"instruction","text":"ברכת הרב את ריבנו מברכים גם ביום וגם בלילה, ומברכים אותה רק בציבור של עשרה. ברכה זו מברך רק החזן הקורא את המגילה לאחר שכרך את כל המגילה.","cond":["megilatEster"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הָרָב אֶת רִיבֵנוּ, וְהַדָּן אֶת דִּינֵנוּ, וְהַנּוֹקֵם אֶת נִקְמָתֵנוּ, וְהַמְשַׁלֵּם גְּמוּל לְכָל אוֹיְבֵי נַפְשֵׁנוּ, וְהַנִּפְרָע לָנוּ מִצָּרֵינוּ. בָּרוּךְ אַתָּה יהוה, הַנִּפְרָע לְעַמּוֹ יִשְׂרָאֵל מִכָּל צָרֵיהֶם, הָאֵל הַמּוֹשִׁיעַ.\n\nבָּרוּךְ יהוה אֱלֹהֵי יִשְׂרָאֵל. אָרוּר הָמָן. בָּרוּךְ מָרְדֳּכִי. אֲרוּרָה זֶרֶשׁ וּוַשְׁתִּי. בְּרוּכָה אֶסְתֵּר. אֲרוּרִים עוֹבְדֵי אֱלִילִים. בְּרוּכִים כָּל יִשְׂרָאֵל. וְגַם חַרְבוֹנָה זָכוּר לְטוֹב.","cond":["megilatEster"]},{"kind":"header","text":"ואתה קדוש","cond":[]},{"kind":"text","text":"וְאַתָּה קָדוֹשׁ יוֹשֵׁב תְּהִלּוֹת יִשְׂרָאֵל: וְקָרָא זֶה אֶל זֶה וְאָמַר: קָדוֹשׁ, קָדוֹשׁ, קָדוֹשׁ יהוה צְבָאוֹת, מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ: וּמְקַבְּלִין דֵּין מִן דֵּין וְאָמְרִין: קַדִּישׁ בִּשְׁמֵי מֵרוֹמַא עִלָאַה בֵּית שְׁכִינְתֵּהּ, קַדִּישׁ עַל אַרְעָא עוֹבַד גְּבוּרְתֵּהּ, קַדִּישׁ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא, יהוה צְבָאוֹת מַלְיָא כָל אַרְעָא זִיו יְקָרֵהּ. וַתִּשָּׂאֵנִי רוּחַ, וָאֶשְׁמַע אַחֲרַי קוֹל רַעַשׁ גָּדוֹל: בָּרוּךְ כְּבוֹד יהוה מִמְּקוֹמוֹ: וּנְטָלַתְנִי רוּחָא, וּשְׁמָעִית בַּתְרַי קַל זִיעַ שַׂגִּיא דִמְשַׁבְּחִין וְאָמְרִין: בְּרִיךְ יְקָרָא דַיהוה מֵאֲתָר בֵּית שְׁכִינְתֵּהּ. יהוה יִמְלֹךְ לְעוֹלָם וָעֶד: יהוה מַלְכוּתֵיהּ קָאֵים לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיהוה אֱלֹהֵי אַבְרָהָם יִצְחָק וְיִשְׂרָאֵל אֲבוֹתֵינוּ, שָׁמְרָה זֹּאת לְעוֹלָם, לְיֵצֶר מַחְשְׁבוֹת לְבַב עַמֶּךָ, וְהָכֵן לְבָבָם אֵלֶיךָ: וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית, וְהִרְבָּה לְהָשִׁיב אַפּוֹ, וְלֹא יָעִיר כָּל חֲמָתוֹ: כִּי אַתָּה יהוה טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ: צִדְקָתְךָ צֶּדֶק לְעוֹלָם, וְתוֹרָתְךָ אֱמֶת: תִּתֵּן אֱמֶת לְיַעֲקֹב, חֶסֶד לְאַבְרָהָם, אֲשֶׁר נִשְׁבַּעְתָּ לַאֲבֹתֵינוּ מִימֵי קֶדֶם: בָּרוּךְ אֲדֹנָי יוֹם יוֹם, יַעֲמָס לָנוּ הָאֵל יְשׁוּעָתֵנוּ, סֶלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב, סֶלָה: יהוה צְבָאוֹת אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":[]},{"kind":"instruction","text":"יכוין למסור נפשו על קדושת שמו יתברך כשאומר זה:","cond":[]},{"kind":"text","text":"בָּרוּךְ אֱלֹהֵינוּ שֶׁבְּרָאָנוּ לִכְבוֹדוֹ, וְהִבְדִּילָנוּ מִן הַתּוֹעִים, וְנָתַן לָנוּ תּוֹרַת אֱמֶת, וְחַיֵּי עוֹלָם נָטַע בְּתוֹכֵנוּ. הוּא יִפְתַּח לִבֵּנוּ בְּתוֹרָתוֹ, וְיָשִׂים בְּלִבֵּנוּ אַהֲבָתוֹ וְיִרְאָתוֹ לַעֲשׂוֹת רְצוֹנוֹ וּלְעָבְדוֹ בְּלֵבָב שָׁלֵם. לְמַעַן לֹא נִיגַע לָרִיק, וְלֹא נֵלֵד לַבֶּהָלָה. יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁנִּשְׁמֹר חֻקֶּיךָ וּמִצְוׂתֶיךָ בָּעוֹלָם הַזֶּה, וְנִזְכֶּה וְנִחְיֶה וְנִירַשׁ טוֹבָה וּבְרָכָה לְחַיֵּי הָעוֹלָם הַבָּא. לְמַעַן יְזַמֶּרְךָ כָבוֹד וְלֹא יִדֹּם, יהוה אֱלֹהַי לְעוֹלָם אוֹדֶךָּ: יהוה חָפֵץ לְמַעַן צִדְקוֹ, יַגְדִּיל תּורָה וְיַאְדִּיר: וְיִבְטְחוּ בְךָ יוֹדְעֵי שְׁמֶךָ, כִּי לֹא עָזַבְתָּ דֹּרְשֶׁיךָ יהוה: יהוה אֲדֹנֵינוּ, מָה אַדִּיר שִׁמְךָ בְּכָל הָאָרֶץ: חִזְקוּ וְיַאֲמֵץ לְבַבְכֶם כָּל הַמְיַחֲלִים לַיהוה:","cond":[]},{"kind":"header","text":"שיר של יום","cond":["musaf"]},{"kind":"instruction","text":"שיר של יום","cond":["musaf"]},{"kind":"text","text":"תְּפִלָּה לְדָוִד, הַטֵּה יהוה אָזְנְךָ עֲנֵנִי, כִּי עָנִי וְאֶבְיוֹן אָנִי: שָׁמְרָה נַפְשִׁי כִּי חָסִיד אָנִי, הוֹשַׁע עַבְדְּךָ, אַתָּה אֱלֹהַי, הַבּוֹטֵחַ אֵלֶיךָ: חָנֵּנִי אֲדֹנָי, כִּי אֵלֶיךָ אֶקְרָא כָּל הַיּוֹם: שַׂמֵּחַ נֶפֶשׁ עַבְדֶּךָ, כִּי אֵלֶיךָ אֲדֹנָי נַפְשִׁי אֶשָּׂא: כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ: הַאֲזִינָה יהוה תְּפִלָּתִי וְהַקְשִׁיבָה בְּקוֹל תַּחֲנוּנוֹתָי: בְּיוֹם צָרָתִי אֶקְרָאֶךָּ כִּי תַעֲנֵנִי: אֵין כָּמוֹךָ בָאֱלֹהִים, אֲדֹנָי, וְאֵין כְּמַעֲשֶׂיךָ: כָּל גּוֹיִם אֲשֶׁר עָשִׂיתָ יָבוֹאוּ וְיִשְׁתַּחֲווּ לְפָנֶיךָ, אֲדֹנָי, וִיכַבְּדוּ לִשְׁמֶךָ: כִּי גָדוֹל אַתָּה וְעֹשֵׂה נִפְלָאוֹת, אַתָּה אֱלֹהִים לְבַדֶּךָ: הוֹרֵנִי יהוה דַּרְכֶּךָ, אֲהַלֵּךְ בַּאֲמִתֶּךָ, יַחֵד לְבָבִי לְיִרְאָה שְׁמֶךָ: אוֹדְךָ אֲדֹנָי אֱלֹהַי בְּכָל לְבָבִי, וַאֲכַבְּדָה שִׁמְךָ לְעוֹלָם: כִּי חַסְדְּךָ גָּדוֹל עָלָי, וְהִצַּלְתָּ נַפְשִׁי מִשְּׁאוֹל תַּחְתִּיָּה: אֱלֹהִים, זֵדִים קָמוּ עָלַי, וַעֲדַת עָרִיצִים בִּקְשׁוּ נַפְשִׁי, וְלֹא שָׂמוּךָ לְנֶגְדָּם: וְאַתָּה אֲדֹנָי אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב חֶסֶד וֶאֱמֶת: פְּנֵה אֵלַי וְחָנֵּנִי, תְּנָה עֻזְּךָ לְעַבְדֶּךָ, וְהוֹשִׁיעָה לְבֶן אֲמָתֶךָ: עֲשֵׂה עִמִּי אוֹת לְטוֹבָה, וְיִרְאוּ שֹׂנְאַי וְיֵבֹשׁוּ, כִּי אַתָּה יהוה עֲזַרְתַּנִי וְנִחַמְתָּנִי:","cond":["musaf","shacharitTachanun"]},{"kind":"text","text":"בֵּית יַעֲקֹב, לְכוּ וְנֵלְכָה בְּאוֹר יהוה: כִּי כָּל הָעַמִּים יֵלְכוּ אִישׁ בְּשֵׁם אֱלֹהָיו, וַאֲנַחְנוּ נֵלֵךְ בְּשֵׁם יהוה אֱלֹהֵינוּ לְעוֹלָם וָעֶד: יְהִי יהוה אֱלֹהֵינוּ עִמָּנוּ כַּאֲשֶׁר הָיָה עִם אבוֹתֵינוּ, אַל יַעַזְבֵנוּ וְאַל יִטְּשֵׁנוּ: לְהַטּות לְבָבֵנוּ אֵלָיו, לָלֶכֶת בְּכָל דְּרָכָיו וְלִשְׁמֹר מִצְוׂתָיו וְחֻקָּיו וּמִשְׁפָּטָיו אֲשֶׁר צִוָּה אֶת אֲבֹתֵינוּ: וְיִהְיוּ דְבָרַי אֵלֶּה אֲשֶׁר הִתְחַנַּנְתִּי לִפְנֵי יהוה קְרֹבִים אֶל יהוה אֱלֹהֵינוּ יוֹמָם וָלָיְלָה, לַעֲשׂוֹת מִשְׁפַּט עַבְדּוֹ וּמִשְׁפַּט עַמּוֹ יִשְׂרָאֵל דְּבַר יוֹם בְּיוֹמוֹ: לְמַעַן דַּעַת כָּל עַמֵּי הָאָרֶץ כִּי יהוה הוּא הָאֱלֹהִים, אֵין עוד:\n\nשִׁיר הַמַּעֲלוֹת לְדָוִד, לוּלֵי יהוה שֶׁהָיָה לָנוּ יֹאמַר נָא יִשְׂרָאֵל: לוּלֵי יהוה שֶׁהָיָה לָנוּ בְּקוּם עָלֵינוּ אָדָם: אֲזַי חַיִּים בְּלָעוּנוּ בַּחֲרוֹת אַפָּם בָּנוּ: אֲזַי הַמַּיִם שְׁטָפוּנוּ נַחְלָה עָבַר עַל נַפְשֵׁנוּ: אֲזַי עָבַר עַל נַפְשֵׁנוּ הַמַּיִם הַזֵּידוֹנִים: בָּרוּךְ יהוה שֶׁלֹּא נְתָנָנוּ טֶרֶף לְשִׁנֵּיהֶם: נַפְשֵׁנוּ כְּצִפּוֹר נִמְלְטָה מִפַּח יוֹקְשִׁים, הַפַּח נִשְׁבָּר וַאֲנַחְנוּ נִמְלָטְנוּ: עֶזְרֵנוּ בְּשֵׁם יהוה, עֹשֵׂה שָׁמַיִם וָאָרֶץ:","cond":["musaf"]},{"kind":"instruction","text":"כשמזכיר \"היום יום פלוני בשבת\" טוב לכון שהוא מקיים מצוות עשה מן התורה של זכירת השבת.","cond":["musaf"]},{"kind":"text","text":"הַיּוֹם יוֹם אֶחָד בַּשַּׁבָּת, הַשִּׁיר שֶׁהָיוּ הַלְוִיִּם אוֹמְרִים עַל הַדּוּכָן:","cond":["musaf","sun","shirOpenD"]},{"kind":"text","text":"הַיּוֹם יוֹם אֶחָד בַּשַּׁבָּת.","cond":["musaf","sun","ShirOpenND"]},{"kind":"text","text":"לְדָוִד מִזְמוֹר, לַיהוה הָאָרֶץ וּמְלוֹאָהּ, תֵּבֵל וְיֹשְׁבֵי בָהּ: כִּי הוּא עַל יַמִּים יְסָדָהּ, וְעַל נְהָרוֹת יְכוֹנְנֶהָ: מִי יַעֲלֶה בְהַר יהוה, וּמִי יָקוּם בִּמְקוֹם קָדְשׁוֹ: נְקִי כַפַּיִם וּבַר לֵבָב, אֲשֶׁר לֹא נָשָׂא לַשָּׁוְא נַפְשִׁי וְלֹא נִשְׁבַּע לְמִרְמָה: יִשָּׂא בְרָכָה מֵאֵת יהוה, וּצְדָקָה מֵאֱלֹהֵי יִשְׁעוֹ: זֶה דּוֹר דֹּרְשָׁיו, מְבַקְשֵׁי פָנֶיךָ יַעֲקֹב סֶלָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וְהִנָּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבוֹא מֶלֶךְ הַכָּבוֹד: מִי זֶה מֶלֶךְ הַכָּבוֹד, יהוה עִזּוּז וְגִבּוֹר, יהוה גִּבּוֹר מִלְחָמָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבֹא מֶלֶךְ הַכָּבוֹד: מִי הוּא זֶה מֶלֶךְ הַכָּבוֹד, יהוה צְבָאוֹת הוּא מֶלֶךְ הַכָּבוֹד סֶלָה:","cond":["musaf","sun"]},{"kind":"text","text":"הַיּוֹם יוֹם שֵׁנִי בַשַּׁבָּת, הַשִּׁיר שֶׁהָיוּ הַלְוִיִּם אוֹמְרִים עַל הַדּוּכָן:","cond":["musaf","mon","shirOpenD"]},{"kind":"text","text":"הַיּוֹם יוֹם שֵׁנִי בַשַּׁבָּת.","cond":["musaf","mon","ShirOpenND"]},{"kind":"text","text":"שִׁיר מִזְמוֹר לִבְנֵי קֹרַח: גָּדוֹל יהוה וּמְהֻלָּל מְאֹד בְּעִיר אֱלֹהֵינוּ הַר קָדְשׁוֹ: יְפֵה נוֹף, מְשׂוֹשׂ כָּל הָאָרֶץ, הַר צִיּוֹן יַרְכְּתֵי צָפוֹן קִרְיַת מֶלֶךְ רָב: אֱלֹהִים בְּאַרְמְנוֹתֶיהָ נוֹדַע לְמִשְׂגָּב: כִּי הִנֵּה הַמְּלָכִים נוֹעֲדוּ עָבְרוּ יַחְדָּו: הֵמָּה רָאוּ כֵּן תָּמָהוּ, נִבְהֲלוּ נֶחְפָּזוּ: רְעָדָה אֲחָזָתַם שָׁם, חִיל כַּיּוֹלֵדָה: בְּרוּחַ קָדִים תְּשַׁבֵּר אֳנִיּוֹת תַּרְשִׁישׁ: כַּאֲשֶׁר שָׁמַעְנוּ כֵּן רָאִינוּ בְּעִיר יהוה צְבָאוֹת בְּעִיר אֱלֹהֵינוּ, אֱלֹהִים יְכוֹנְנֶהָ עַד עוֹלָם סֶלָה: דִּמִּינוּ אֱלֹהִים חַסְדֶּךָ בְּקֶרֶב הֵיכָלֶךָ: כְּשִׁמְךָ אֱלֹהִים כֵּן תְּהִלָּתְךָ עַל קַצְוֵי אֶרֶץ, צֶדֶק מָלְאָה יְמִינֶךָ: יִשְׂמַח הַר צִיּוֹן, תָּגֵלְנָה בְּנוֹת יְהוּדָה, לְמַעַן מִשְׁפָּטֶיךָ: סֹבּוּ צִיּוֹן וְהַקִּיפוּהָ, סִפְרוּ מִגְדָּלֶיהָ: שִׁיתוּ לִבְּכֶם לְחֵילָה, פַּסְּגוּ אַרְמְנוֹתֶיהָ, לְמַעַן תְּסַפְּרוּ לְדוֹר אַחֲרוֹן: כִּי זֶה אֱלֹהִים אֱלֹהֵינוּ עוֹלָם וָעֶד, הוּא יְנַהֲגֵנוּ עַל מוּת:","cond":["musaf","mon"]},{"kind":"text","text":"הַיּוֹם יוֹם שְׁלִישִׁי בַשַּׁבָּת, הַשִּׁיר שֶׁהָיוּ הַלְוִיִּם אוֹמְרִים עַל הַדּוּכָן:","cond":["musaf","tue","shirOpenD"]},{"kind":"text","text":"הַיּוֹם יוֹם שְׁלִישִׁי בַשַּׁבָּת.","cond":["musaf","tue","ShirOpenND"]},{"kind":"text","text":"מִזְמוֹר לְאָסָף, אֱלֹהִים נִצָּב בַּעֲדַת אֵל, בְּקֶרֶב אֱלֹהִים יִשְׁפֹּט: עַד מָתַי תִּשְׁפְּטוּ עָוֶל וּפְנֵי רְשָׁעִים תִּשְׂאוּ סֶלָה: שִׁפְטוּ דַל וְיָתוֹם, עָנִי וָרָשׁ הַצְדִּיקוּ: פַּלְּטוּ דַל וְאֶבְיוֹן, מִיַּד רְשָׁעִים הַצִּילוּ: לֹא יָדְעוּ וְלֹא יָבִינוּ, בַּחֲשֵׁכָה יִתְהַלָּכוּ, יִמּוֹטוּ כָּל מוֹסְדֵי אָרֶץ: אֲנִי אָמַרְתִּי אֱלֹהִים אַתֶּם וּבְנֵי עֶלְיוֹן כֻּלְּכֶם: אָכֵן כְּאָדָם תְּמוּתוּן וּכְאַחַד הַשָּׂרִים תִּפֹּלוּ: קוּמָה אֱלֹהִים שָׁפְטָה הָאָרֶץ, כִּי אַתָּה תִנְחַל בְּכָל הַגּוֹיִם:","cond":["musaf","tue"]},{"kind":"text","text":"הַיּוֹם יוֹם רְבִיעִי בַשַּׁבָּת, הַשִּׁיר שֶׁהָיוּ הַלְוִיִּם אוֹמְרִים עַל הַדּוּכָן:","cond":["musaf","wed","shirOpenD"]},{"kind":"text","text":"הַיּוֹם יוֹם רְבִיעִי בַשַּׁבָּת.","cond":["musaf","wed","ShirOpenND"]},{"kind":"text","text":"אֵל נְקָמוֹת יהוה, אֵל נְקָמוֹת הוֹפִיעַ: הִנָּשֵׂא שֹׁפֵט הָאָרֶץ, הָשֵׁב גְּמוּל עַל גֵּאִים: עַד מָתַי רְשָׁעִים, יהוה, עַד מָתַי רְשָׁעִים יַעֲלֹזוּ: יַבִּיעוּ יְדַבְּרוּ עָתָק, יִתְאַמְּרוּ כָּל פֹעֲלֵי אָוֶן: עַמְּךָ יהוה יְדַכְּאוּ, וְנַחֲלָתְךָ יְעַנּוּ: אַלְמָנָה וְגֵר יַהֲרֹגוּ, וִיתוֹמִים יְרַצֵּחוּ: וַיֹּאמְרוּ לֹא יִרְאֶה יָהּ, וְלֹא יָבִין אֱלֹהֵי יַעֲקֹב: בִּינוּ בֹּעֲרִים בָּעָם, וּכְסִילִים מָתַי תַּשְׂכִּילוּ: הַנֹּטַע אֹזֶן הֲלֹא יִשְׁמָע, אִם יֹצֵר עַיִן הֲלֹא יַבִּיט: הֲיֹסֵר גּוֹיִם הֲלֹא יוֹכִיחַ, הַמְלַמֵּד אָדָם דָּעַת: יהוה יֹדֵעַ מַחְשְׁבוֹת אָדָם כִּי הֵמָּה הָבֶל: אַשְׁרֵי הַגֶּבֶר אֲשֶׁר תְּיַסְּרֶנּוּ יָּהּ, וּמִתּוֹרָתְךָ תְלַמְּדֶנּוּ: לְהַשְׁקִיט לוֹ מִימֵי רָע, עַד יִכָּרֶה לָרָשָׁע שָׁחַת: כִּי לֹא יִטֹּשׁ יהוה עַמּוֹ, וְנַחֲלָתוֹ לֹא יַעֲזֹב: כִּי עַד צֶדֶק יָשׁוּב מִשְׁפָּט, וְאַחֲרָיו כָּל יִשְׁרֵי לֵב: מִי יָקוּם לִי עִם מְרֵעִים, מִי יִתְיַצֵּב לִי עִם פֹּעֲלֵי אָוֶן: לוּלֵי יהוה עֶזְרָתָה לִּי, כִּמְעַט שָׁכְנָה דוּמָה נַפְשִׁי: אִם אָמַרְתִּי מָטָה רַגְלִי, חַסְדְּךָ יהוה יִסְעָדֵנִי: בְּרֹב שַׂרְעַפַּי בְּקִרְבִּי, תַּנְחוּמֶיךָ יְשַׁעַשְׁעוּ נַפְשִׁי: הַיְחָבְרְךָ כִּסֵּא הַוּוֹת, יֹצֵר עָמָל עֲלֵי חֹק: יָגוֹדּוּ עַל נֶפֶשׁ צַדִּיק, וְדָם נָקִי יַרְשִׁיעוּ: וַיְהִי יהוה לִי לְמִשְׂגָּב, וֵאלֹהַי לְצוּר מַחְסִי: וַיָּשֶׁב עֲלֵיהֶם אֶת אוֹנָם וּבְרָעָתָם יַצְמִיתֵם, יַצְמִיתֵם יהוה אֱלֹהֵינוּ:","cond":["musaf","wed"]},{"kind":"text","text":"הַיּוֹם יוֹם חֲמִישִׁי בַשַּׁבָּת, הַשִּׁיר שֶׁהָיוּ הַלְוִיִּם אוֹמְרִים עַל הַדּוּכָן:","cond":["musaf","thu","shirOpenD"]},{"kind":"text","text":"הַיּוֹם יוֹם חֲמִישִׁי בַשַּׁבָּת.","cond":["musaf","thu","ShirOpenND"]},{"kind":"text","text":"לַמְנַצֵּחַ עַל הַגִּתִּית לְאָסָף: הַרְנִינוּ לֵאלֹהִים עֻזֵּנוּ, הָרִיעוּ לֵאלֹהֵי יַעֲקֹב: שְׂאוּ זִמְרָה וּתְנוּ תֹף, כִּנּוֹר נָעִים עִם נָבֶל: תִּקְעוּ בַחֹדֶשׁ שׁוֹפָר, בַּכֵּסֶה לְיוֹם חַגֵּנוּ: כִּי חֹק לְיִשְׂרָאֵל הוּא, מִשְׁפָּט לֵאלֹהֵי יַעֲקֹב: עֵדוּת בִּיהוֹסֵף שָׂמוֹ בְּצֵאתוֹ עַל אֶרֶץ מִצְרָיִם, שְׂפַת לֹא יָדַעְתִּי אֶשְׁמָע: הֲסִירוֹתִי מִסֵּבֶל שִׁכְמוֹ, כַּפָּיו מִדּוּד תַּעֲבֹרְנָה: בַּצָּרָה קָרָאתָ וָאֲחַלְּצֶךָּ, אֶעֶנְךָ בְּסֵתֶר רַעַם, אֶבְחָנְךָ עַל מֵי מְרִיבָה סֶלָה: שְׁמַע עַמִּי וְאָעִידָה בָּךְ, יִשְׂרָאֵל אִם תִּשְׁמַע לִי: לֹא יִהְיֶה בְךָ אֵל זָר, וְלֹא תִשְׁתַּחֲוֶה לְאֵל נֵכָר: אָנֹכִי יהוה אֱלֹהֶיךָ הַמַּעַלְךָ מֵאֶרֶץ מִצְרָיִם, הַרְחֶב פִּיךָ וַאֲמַלְאֵהוּ: וְלֹא שָׁמַע עַמִּי לְקוֹלִי, וְיִשְׂרָאֵל לֹא אָבָה לִי: וָאֲשַׁלְּחֵהוּ בִּשְׁרִירוּת לִבָּם, יֵלְכוּ בְּמוֹעֲצוֹתֵיהֶם: לוּ עַמִּי שֹׁמֵעַ לִי, יִשְׂרָאֵל בִּדְרָכַי יְהַלֵּכוּ: כִּמְעַט אוֹיְבֵיהֶם אַכְנִיעַ, וְעַל צָרֵיהֶם אָשִׁיב יָדִי: מְשַׂנְאֵי יהוה יְכַחֲשׁוּ לוֹ, וִיהִי עִתָּם לְעוֹלָם: וַיַּאֲכִילֵהוּ מֵחֵלֶב חִטָּה, וּמִצּוּר, דְּבַשׁ אַשְׂבִּיעֶךָ:","cond":["musaf","thu"]},{"kind":"text","text":"הַיּוֹם יוֹם הַשִּׁשִּׁי בַשַּׁבָּת, הַשִּׁיר שֶׁהָיוּ הַלְוִיִּם אוֹמְרִים עַל הַדּוּכָן:","cond":["musaf","fri","shirOpenD"]},{"kind":"text","text":"הַיּוֹם יוֹם הַשִּׁשִּׁי בַשַּׁבָּת.","cond":["musaf","fri","ShirOpenND"]},{"kind":"text","text":"יהוה מָלָךְ גֵּאוּת לָבֵשׁ, לָבֵשׁ יהוה עֹז הִתְאַזָּר, אַף תִּכּוֹן תֵּבֵל בַּל תִּמּוֹט: נָכוֹן כִּסְאֲךָ מֵאָז, מֵעוֹלָם אָתָּה: נָשְׂאוּ נְהָרוֹת, יהוה, נָשְׂאוּ נְהָרוֹת קוֹלָם, יִשְׂאוּ נְהָרוֹת דָכְיָם: מִקֹּלוֹת מַיִם רַבִּים, אַדִּירִים מִשְׁבְּרֵי יָם, אַדִּיר בַּמָּרוֹם יהוה: עֵדֹתֶיךָ נֶאֶמְנוּ מְאֹד לְבֵיתְךָ נַאֲוָה קֹדֶשׁ, יהוה, לְאֹרֶךְ יָמִים:","cond":["musaf","fri"]},{"kind":"instruction","text":"בבית האבל אומרים מזמור זה:","cond":["musaf"]},{"kind":"text","text":"לַמְנַצֵּחַ לִבְנֵי קֹרַח מִזְמוֹר: שִׁמְעוּ זֹאת כָּל הָעַמִּים, הַאֲזִינוּ כָּל יֹשְׁבֵי חָלֶד: גַּם בְּנֵי אָדָם, גַּם בְּנֵי אִישׁ, יַחַד עָשִׁיר וְאֶבְיוֹן: פִּי יְדַבֵּר חָכְמוֹת, וְהָגוּת לִבִּי תְבוּנוֹת: אַטֶּה לְמָשָׁל אָזְנִי, אֶפְתַּח בְּכִנּוֹר חִידָתִי: לָמָּה אִירָא בִּימֵי רָע, עֲוׂן עֲקֵבַי יְסוּבֵּנִי: הַבֹּטְחִים עַל חֵילָם, וּבְרֹב עָשְׁרָם יִתְהַלָּלוּ: אָח לֹא פָדֹה יִפְדֶּה אִישׁ, לֹא יִתֵּן לֵאלֹהִים כָּפְרוֹ: וְיֵקַר פִּדְיוֹן נַפְשָׁם, וְחָדַל לְעוֹלָם: וִיחִי עוֹד לָנֶצַח, לֹא יִרְאֶה הַשָּׁחַת: כִּי יִרְאֶה חֲכָמִים יָמוּתוּ, יַחַד כְּסִיל וָבַעַר יֹאבֵדוּ, וְעָזְבוּ לַאֲחֵרִים חֵילָם: קִרְבָּם בָּתֵּימוֹ לְעוֹלָם, מִשְׁכְּנֹתָם לְדֹר וָדֹר, קָרְאוּ בִשְׁמוֹתָם עֲלֵי אֲדָמוֹת: וְאָדָם בִּיקָר בַּל יָלִין, נִמְשַׁל כַּבְּהֵמוֹת נִדְמוּ: זֶה דַרְכָּם כֵּסֶל לָמוֹ, וְאַחֲרֵיהֶם בְּפִיהֶם יִרְצוּ סֶלָה: כַּצֹּאן לִשְׁאוֹל שַׁתּוּ מָוֶת יִרְעֵם, וַיִּרְדּוּ בָם יְשָׁרִים לַבֹּקֶר, וְצוּרָם לְבַלּוֹת שְׁאוֹל מִזְּבֻל לוֹ: אַךְ אֱלֹהִים יִפְדֶּה נַפְשִׁי מִיַּד שְׁאוֹל, כִּי יִקָּחֵנִי סֶלָה: אַל תִּירָא כִּי יַעֲשִׁר אִישׁ, כִּי יִרְבֶּה כְּבוֹד בֵּיתוֹ: כִּי לֹא בְמוֹתוֹ יִקַּח הַכֹּל, לֹא יֵרֵד אַחֲרָיו כְּבוֹדוֹ: כִּי נַפְשׁוֹ בְּחַיָּיו יְבָרֵךְ, וְיוֹדֻךָ כִּי תֵיטִיב לָךְ: תָּבוֹא עַד דּוֹר אֲבוֹתָיו, עַד נֵצַח לֹא יִרְאוּ אוֹר: אָדָם בִּיקָר וְלֹא יָבִין נִמְשַׁל כַּבְּהֵמוֹת נִדְמוּ:","cond":["musaf"]},{"kind":"header","text":"הושיענו","cond":["musaf"]},{"kind":"instruction","text":"בכל יום אחרי שיר של יום אומרים:","cond":["musaf"]},{"kind":"text","text":"הוֹשִׁיעֵנוּ יהוה אֱלֹהֵינוּ וְקַבְּצֵנוּ מִן הַגּוֹיִם, לְהֹדוֹת לְשֵׁם קָדְשֶׁךָ לְהִשְׁתַּבֵּחַ בִּתְהִלָּתֶךָ: בָּרוּךְ יהוה אֱלֹהֵי יִשְׂרָאֵל מִן הָעוֹלָם וְעַד הָעוֹלָם, וְאָמַר כָּל הָעָם אָמֵן הַלְלוּיָהּ: בָּרוּךְ יהוה מִצִּיּוֹן, שֹׁכֵן יְרוּשָׁלִָם הַלְלוּיָהּ: בָּרוּךְ יהוה אֱלֹהִים אֱלֹהֵי יִשְׂרָאֵל, עֹשֵׂה נִפְלָאוֹת לְבַדּוֹ: וּבָרוּךְ שֵׁם כְּבוֹדוֹ לְעוֹלָם, וְיִמָּלֵא כְבוֹדוֹ אֶת כָּל הָאָרֶץ, אָמֵן וְאָמֵן:","cond":["musaf"]},{"kind":"special","text":"מזמור לשבעה עשר בתמוז:","cond":["musaf","17tammuz"]},{"kind":"text","text":"מִזְמוֹר לְאָסָף, אֱלֹהִים, בָּאוּ גוֹיִם בְּנַחֲלָתֶךָ טִמְּאוּ אֶת הֵיכַל קָדְשֶׁךָ, שָׂמוּ אֶת יְרוּשָׁלַיִם לְעִיִּים: נָתְנוּ אֶת נִבְלַת עֲבָדֶיךָ מַאֲכָל לְעוֹף הַשָּׁמָיִם, בְּשַׂר חֲסִידֶיךָ לְחַיְתוֹ אָרֶץ: שָׁפְכוּ דָמָם כַּמַּיִם סְבִיבוֹת יְרוּשָׁלִָם וְאֵין קוֹבֵר: הָיִינוּ חֶרְפָּה לִשְׁכֵנֵינוּ, לַעַג וָקֶלֶס לִסְבִיבוֹתֵינוּ: עַד מָה יהוה תֶּאֱנַף לָנֶצַח, תִּבְעַר כְּמוֹ אֵשׁ קִנְאָתֶךָ: שְׁפֹךְ חֲמָתְךָ אֶל הַגּוֹיִם אֲשֶׁר לֹא יְדָעוּךָ, וְעַל מַמְלָכוֹת אֲשֶׁר בְּשִׁמְךָ לֹא קָרָאוּ: כִּי אָכַל אֶת יַעֲקֹב וְאֶת נָוֵהוּ הֵשַׁמּוּ: אַל תִּזְכָּר לָנוּ עֲוׂנֹת רִאשֹׁנִים, מַהֵר יְקַדְּמוּנוּ רַחֲמֶיךָ כִּי דַלּוֹנוּ מְאֹד: עָזְרֵנוּ אֱלֹהֵי יִשְׁעֵנוּ עַל דְּבַר כְּבוֹד שְׁמֶךָ, וְהַצִּילֵנוּ וְכַפֵּר עַל חַטֹּאתֵינוּ לְמַעַן שְׁמֶךָ: לָמָּה יֹאמְרוּ הַגּוֹיִם אַיֵּה אֱלֹהֵיהֶם, יִוָּדַע בַּגּוֹיִם לְעֵינֵינוּ נִקְמַת דַּם עֲבָדֶיךָ הַשָּׁפוּךְ: תָּבוֹא לְפָנֶיךָ אֶנְקַת אָסִיר כְּגֹדֶל זְרוֹעֲךָ הוֹתֵר בְּנֵי תְמוּתָה: וְהָשֵׁב לִשְׁכֵנֵינוּ שִׁבְעָתַיִם אֶל חֵיקָם חֶרְפָּתָם אֲשֶׁר חֵרְפוּךָ אֲדֹנָי: וַאֲנַחְנוּ עַמְּךָ וְצֹאן מַרְעִיתֶךָ נוֹדֶה לְּךָ לְעוֹלָם, לְדֹר וָדֹר נְסַפֵּר תְּהִלָּתֶךָ:","cond":["musaf","17tammuz"]},{"kind":"special","text":"מזמור למחרת יום הכיפורים:","cond":["musaf","11tishrei"]},{"kind":"text","text":"לַמְנַצֵּחַ לִבְנֵי-קֹרַח מִזְמוֹר: רָצִיתָ יהוה אַרְצֶךָ, שַׁבְתָּ שְׁבִית יַעֲקֹב: נָשָׂאתָ עֲוׂן עַמֶּךָ, כִּסִּיתָ כָל-חַטָּאתָם סֶלָה: אָסַפְתָּ כָל-עֶבְרָתֶךָ, הֱשִׁיבוֹתָ מֵחֲרוֹן אַפֶּךָ: שׁוּבֵנוּ אֱלֹהֵי יִשְׁעֵנוּ, וְהָפֵר כַּעַסְךָ עִמָּנוּ: הַלְעוֹלָם תֶּאֱנַף-בָּנוּ, תִּמְשֹׁךְ אַפְּךָ לְדֹר וָדֹר: הֲלֹא-אַתָּה תָּשׁוּב תְּחַיֵּנוּ, וְעַמְּךָ יִשְׂמְחוּ-בָךְ: הַרְאֵנוּ יהוה חַסְדֶּךָ, וְיֶשְׁעֲךָ תִּתֶּן-לָנוּ: אֶשְׁמְעָה מַה-יְדַבֵּר הָאֵל יהוה, כִּי יְדַבֵּר שָׁלוֹם אֶל-עַמּוֹ וְאֶל-חֲסִידָיו, וְאַל-יָשׁוּבוּ לְכִסְלָה: אַךְ קָרוֹב לִירֵאָיו יִשְׁעוֹ, לִשְׁכֹּן כָּבוֹד בְּאַרְצֵנוּ: חֶסֶד-וֶאֱמֶת נִפְגָּשׁוּ, צֶדֶק וְשָׁלוֹם נָשָׁקוּ: אֱמֶת מֵאֶרֶץ תִּצְמָח, וְצֶדֶק מִשָּׁמַיִם נִשְׁקָף: גַּם-יהוה יִתֵּן הַטּוֹב, וְאַרְצֵנוּ תִּתֵּן יְבוּלָהּ: צֶדֶק לְפָנָיו יְהַלֵּךְ, וְיָשֵׂם לְדֶרֶךְ פְּעָמָיו:","cond":["musaf","11tishrei"]},{"kind":"special","text":"מזמור לצום גדליה ולעשרה בטבת:","cond":["musaf","gedalya"]},{"kind":"text","text":"שִׁיר מִזְמוֹר לְאָסָף: אֱלֹהִים אַל דֳּמִי לָךְ, אַל תֶּחֱרַשׁ וְאַל תִּשְׁקֹט אֵל: כִּי הִנֵּה אוֹיְבֶיךָ יֶהֱמָיוּן, וּמְשַׂנְאֶיךָ נָשְׂאוּ רֹאשׁ: עַל עַמְּךָ יַעֲרִימוּ סוֹד, וְיִתְיָעֲצוּ עַל צְפוּנֶיךָ: אָמְרוּ לְכוּ וְנַכְחִידֵם מִגּוֹי, וְלֹא יִזָּכֵר שֵׁם יִשְׂרָאֵל עוֹד: כִּי נוֹעֲצוּ לֵב יַחְדָּו, עָלֶיךָ בְּרִית יִכְרֹתוּ: אָהֳלֵי אֱדוֹם וְיִשְׁמְעֵאלִים, מוֹאָב וְהַגְרִים: גְּבָל וְעַמּוֹן וַעֲמָלֵק, פְּלֶשֶׁת עִם יֹשְׁבֵי צוֹר: גַּם אַשּׁוּר נִלְוָה עִמָּם, הָיוּ זְרוֹעַ לִבְנֵי לוֹט סֶלָה: עֲשֵׂה לָהֶם כְּמִדְיָן, כְּסִיסְרָא כְיָבִין בְּנַחַל קִישׁוֹן: נִשְׁמְדוּ בְעֵין דֹּאר, הָיוּ דֹּמֶן לָאֲדָמָה: שִׁיתֵמוֹ נְדִיבֵמוֹ כְּעֹרֵב וְכִזְאֵב, וּכְזֶבַח וּכְצַלְמֻנָּע כָּל נְסִיכֵמוֹ: אֲשֶׁר אָמְרוּ נִירְשָׁה לָּנוּ, אֵת נְאוֹת אֱלֹהִים: אֱלֹהַי, שִׁיתֵמוֹ כַגַּלְגַּל, כְּקַשׁ לִפְנֵי רוּחַ: כְּאֵשׁ תִּבְעַר יָעַר, וּכְלֶהָבָה תְּלַהֵט הָרִים: כֵּן תִּרְדְּפֵם בְּסַעֲרֶךָ, וּבְסוּפָתְךָ תְבַהֲלֵם: מַלֵּא פְנֵיהֶם קָלוֹן, וִיבַקְשׁוּ שִׁמְךָ יהוה: יֵבֹשׁוּ וְיִבָּהֲלוּ עֲדֵי עַד, וְיַחְפְּרוּ וְיֹאבֵדוּ: וְיֵדְעוּ כִּי אַתָּה שִׁמְךָ יהוה לְבַדֶּךָ, עֶלְיוֹן עַל כָּל הָאָרֶץ:","cond":["musaf","gedalya"]},{"kind":"special","text":"מזמור לצום גדליה ולעשרה בטבת:","cond":["musaf","10tevet"]},{"kind":"text","text":"שִׁיר מִזְמוֹר לְאָסָף: אֱלֹהִים אַל דֳּמִי לָךְ, אַל תֶּחֱרַשׁ וְאַל תִּשְׁקֹט אֵל: כִּי הִנֵּה אוֹיְבֶיךָ יֶהֱמָיוּן, וּמְשַׂנְאֶיךָ נָשְׂאוּ רֹאשׁ: עַל עַמְּךָ יַעֲרִימוּ סוֹד, וְיִתְיָעֲצוּ עַל צְפוּנֶיךָ: אָמְרוּ לְכוּ וְנַכְחִידֵם מִגּוֹי, וְלֹא יִזָּכֵר שֵׁם יִשְׂרָאֵל עוֹד: כִּי נוֹעֲצוּ לֵב יַחְדָּו, עָלֶיךָ בְּרִית יִכְרֹתוּ: אָהֳלֵי אֱדוֹם וְיִשְׁמְעֵאלִים, מוֹאָב וְהַגְרִים: גְּבָל וְעַמּוֹן וַעֲמָלֵק, פְּלֶשֶׁת עִם יֹשְׁבֵי צוֹר: גַּם אַשּׁוּר נִלְוָה עִמָּם, הָיוּ זְרוֹעַ לִבְנֵי לוֹט סֶלָה: עֲשֵׂה לָהֶם כְּמִדְיָן, כְּסִיסְרָא כְיָבִין בְּנַחַל קִישׁוֹן: נִשְׁמְדוּ בְעֵין דֹּאר, הָיוּ דֹּמֶן לָאֲדָמָה: שִׁיתֵמוֹ נְדִיבֵמוֹ כְּעֹרֵב וְכִזְאֵב, וּכְזֶבַח וּכְצַלְמֻנָּע כָּל נְסִיכֵמוֹ: אֲשֶׁר אָמְרוּ נִירְשָׁה לָּנוּ, אֵת נְאוֹת אֱלֹהִים: אֱלֹהַי, שִׁיתֵמוֹ כַגַּלְגַּל, כְּקַשׁ לִפְנֵי רוּחַ: כְּאֵשׁ תִּבְעַר יָעַר, וּכְלֶהָבָה תְּלַהֵט הָרִים: כֵּן תִּרְדְּפֵם בְּסַעֲרֶךָ, וּבְסוּפָתְךָ תְבַהֲלֵם: מַלֵּא פְנֵיהֶם קָלוֹן, וִיבַקְשׁוּ שִׁמְךָ יהוה: יֵבֹשׁוּ וְיִבָּהֲלוּ עֲדֵי עַד, וְיַחְפְּרוּ וְיֹאבֵדוּ: וְיֵדְעוּ כִּי אַתָּה שִׁמְךָ יהוה לְבַדֶּךָ, עֶלְיוֹן עַל כָּל הָאָרֶץ:","cond":["musaf","10tevet"]},{"kind":"special","text":"מזמור לתענית אסתר ולפורים:","cond":["musaf","purim"]},{"kind":"text","text":"לַמְנַצֵּחַ עַל אַיֶּלֶת הַשַּׁחַר, מִזְמוֹר לְדָוִד: אֵלִי אֵלִי לָמָה עֲזַבְתָּנִי, רָחוֹק מִישׁוּעָתִי דִּבְרֵי שַׁאֲגָתִי: אֱלֹהַי, אֶקְרָא יוֹמָם וְלֹא תַעֲנֶה, וְלַיְלָה וְלֹא דוּמִיָּה לִי: וְאַתָּה קָדוֹשׁ, יוֹשֵׁב תְּהִלּוֹת יִשְׂרָאֵל: בְּךָ בָּטְחוּ אֲבֹתֵינוּ, בָּטְחוּ וַתְּפַלְּטֵמוֹ: אֵלֶיךָ זָעֲקוּ וְנִמְלָטוּ, בְּךָ בָטְחוּ וְלֹא בוֹשׁוּ: וְאָנֹכִי תוֹלַעַת וְלֹא אִישׁ, חֶרְפַּת אָדָם וּבְזוּי עָם: כָּל רֹאַי יַלְעִגוּ לִי, יַפְטִירוּ בְשָׂפָה יָנִיעוּ רֹאשׁ: גֹּל אֶל יהוה יְפַלְּטֵהוּ, יַצִּילֵהוּ כִּי חָפֵץ בּוֹ: כִּי אַתָּה גֹחִי מִבָּטֶן, מַבְטִיחִי עַל שְׁדֵי אִמִּי: עָלֶיךָ הָשְׁלַכְתִּי מֵרָחֶם, מִבֶּטֶן אִמִּי אֵלִי אָתָּה אַל תִּרְחַק מִמֶּנִּי כִּי צָרָה קְרוֹבָה, כִּי אֵין עוֹזֵר: סְבָבוּנִי פָּרִים רַבִּים, אַבִּירֵי בָשָׁן כִּתְּרוּנִי: פָּצוּ עָלַי פִּיהֶם, אַרְיֵה טֹרֵף וְשֹׁאֵג: כַּמַּיִם נִשְׁפַּכְתִּי וְהִתְפָּרְדוּ כָּל עַצְמוֹתָי, הָיָה לִבִּי כַּדּוֹנָג, נָמֵס בְּתוֹךְ מֵעָי: יָבֵשׁ כַּחֶרֶשׂ כֹּחִי וּלְשׁוֹנִי מֻדְבָּק מַלְקוֹחָי, וְלַעֲפַר מָוֶת תִּשְׁפְּתֵנִי: כִּי סְבָבוּנִי כְּלָבִים, עֲדַת מְרֵעִים הִקִּיפוּנִי, כָּאֲרִי יָדַי וְרַגְלָי: אֲסַפֵּר כָּל עַצְמוֹתָי, הֵמָּה יַבִּיטוּ יִרְאוּ בִי: יְחַלְּקוּ בְגָדַי לָהֶם, וְעַל לְבוּשִׁי יַפִּילוּ גוֹרָל: וְאַתָּה יהוה אַל תִּרְחָק, אֱיָלוּתִי לְעֶזְרָתִי חוּשָׁה: הַצִּילָה מֵחֶרֶב נַפְשִׁי, מִיַּד כֶּלֶב יְחִידָתִי: הוֹשִׁיעֵנִי מִפִּי אַרְיֵה, וּמִקַּרְנֵי רֵמִים עֲנִיתָנִי: אֲסַפְּרָה שִׁמְךָ לְאֶחָי, בְּתוֹךְ קָהָל אֲהַלְלֶךָּ: יִרְאֵי יהוה הַלְלוּהוּ, כָּל זֶרַע יַעֲקֹב כַּבְּדוּהוּ, וְגוּרוּ מִמֶּנּוּ כָּל זֶרַע יִשְׂרָאֵל: כִּי לֹא בָזָה וְלֹא שִׁקַּץ עֱנוּת עָנִי, וְלֹא הִסְתִּיר פָּנָיו מִמֶּנּוּ, וּבְשַׁוְּעוֹ אֵלָיו שָׁמֵעַ: מֵאִתְּךָ תְהִלָּתִי בְּקָהָל רָב, נְדָרַי אֲשַׁלֵּם נֶגֶד יְרֵאָיו: יֹאכְלוּ עֲנָוִים וְיִשְׂבָּעוּ, יְהַלְלוּ יהוה דֹּרְשָׁיו, יְחִי לְבַבְכֶם לָעַד: יִזְכְּרוּ וְיָשֻׁבוּ אֶל יהוה כָּל אַפְסֵי אָרֶץ, וְיִשְׁתַּחֲווּ לְפָנֶיךָ כָּל מִשְׁפְּחוֹת גּוֹיִם: כִּי לַיהוה הַמְּלוּכָה, וּמֹשֵׁל בַּגּוֹיִם: אָכְלוּ וַיִּשְׁתַּחֲוּוּ כָּל דִּשְׁנֵי אֶרֶץ, לְפָנָיו יִכְרְעוּ כָּל יוֹרְדֵי עָפָר, וְנַפְשׁוֹ לֹא חִיָּה: זֶרַע יַעַבְדֶנּוּ, יְסֻפַּר לַאדֹנָי לַדּוֹר: יָבֹאוּ וְיַגִּידוּ צִדְקָתוֹ, לְעַם נוֹלָד כִּי עָשָׂה:","cond":["musaf","purim"]},{"kind":"special","text":"מזמור לתענית אסתר ולפורים:","cond":["musaf","ester"]},{"kind":"text","text":"לַמְנַצֵּחַ עַל אַיֶּלֶת הַשַּׁחַר, מִזְמוֹר לְדָוִד: אֵלִי אֵלִי לָמָה עֲזַבְתָּנִי, רָחוֹק מִישׁוּעָתִי דִּבְרֵי שַׁאֲגָתִי: אֱלֹהַי, אֶקְרָא יוֹמָם וְלֹא תַעֲנֶה, וְלַיְלָה וְלֹא דוּמִיָּה לִי: וְאַתָּה קָדוֹשׁ, יוֹשֵׁב תְּהִלּוֹת יִשְׂרָאֵל: בְּךָ בָּטְחוּ אֲבֹתֵינוּ, בָּטְחוּ וַתְּפַלְּטֵמוֹ: אֵלֶיךָ זָעֲקוּ וְנִמְלָטוּ, בְּךָ בָטְחוּ וְלֹא בוֹשׁוּ: וְאָנֹכִי תוֹלַעַת וְלֹא אִישׁ, חֶרְפַּת אָדָם וּבְזוּי עָם: כָּל רֹאַי יַלְעִגוּ לִי, יַפְטִירוּ בְשָׂפָה יָנִיעוּ רֹאשׁ: גֹּל אֶל יהוה יְפַלְּטֵהוּ, יַצִּילֵהוּ כִּי חָפֵץ בּוֹ: כִּי אַתָּה גֹחִי מִבָּטֶן, מַבְטִיחִי עַל שְׁדֵי אִמִּי: עָלֶיךָ הָשְׁלַכְתִּי מֵרָחֶם, מִבֶּטֶן אִמִּי אֵלִי אָתָּה אַל תִּרְחַק מִמֶּנִּי כִּי צָרָה קְרוֹבָה, כִּי אֵין עוֹזֵר: סְבָבוּנִי פָּרִים רַבִּים, אַבִּירֵי בָשָׁן כִּתְּרוּנִי: פָּצוּ עָלַי פִּיהֶם, אַרְיֵה טֹרֵף וְשֹׁאֵג: כַּמַּיִם נִשְׁפַּכְתִּי וְהִתְפָּרְדוּ כָּל עַצְמוֹתָי, הָיָה לִבִּי כַּדּוֹנָג, נָמֵס בְּתוֹךְ מֵעָי: יָבֵשׁ כַּחֶרֶשׂ כֹּחִי וּלְשׁוֹנִי מֻדְבָּק מַלְקוֹחָי, וְלַעֲפַר מָוֶת תִּשְׁפְּתֵנִי: כִּי סְבָבוּנִי כְּלָבִים, עֲדַת מְרֵעִים הִקִּיפוּנִי, כָּאֲרִי יָדַי וְרַגְלָי: אֲסַפֵּר כָּל עַצְמוֹתָי, הֵמָּה יַבִּיטוּ יִרְאוּ בִי: יְחַלְּקוּ בְגָדַי לָהֶם, וְעַל לְבוּשִׁי יַפִּילוּ גוֹרָל: וְאַתָּה יהוה אַל תִּרְחָק, אֱיָלוּתִי לְעֶזְרָתִי חוּשָׁה: הַצִּילָה מֵחֶרֶב נַפְשִׁי, מִיַּד כֶּלֶב יְחִידָתִי: הוֹשִׁיעֵנִי מִפִּי אַרְיֵה, וּמִקַּרְנֵי רֵמִים עֲנִיתָנִי: אֲסַפְּרָה שִׁמְךָ לְאֶחָי, בְּתוֹךְ קָהָל אֲהַלְלֶךָּ: יִרְאֵי יהוה הַלְלוּהוּ, כָּל זֶרַע יַעֲקֹב כַּבְּדוּהוּ, וְגוּרוּ מִמֶּנּוּ כָּל זֶרַע יִשְׂרָאֵל: כִּי לֹא בָזָה וְלֹא שִׁקַּץ עֱנוּת עָנִי, וְלֹא הִסְתִּיר פָּנָיו מִמֶּנּוּ, וּבְשַׁוְּעוֹ אֵלָיו שָׁמֵעַ: מֵאִתְּךָ תְהִלָּתִי בְּקָהָל רָב, נְדָרַי אֲשַׁלֵּם נֶגֶד יְרֵאָיו: יֹאכְלוּ עֲנָוִים וְיִשְׂבָּעוּ, יְהַלְלוּ יהוה דֹּרְשָׁיו, יְחִי לְבַבְכֶם לָעַד: יִזְכְּרוּ וְיָשֻׁבוּ אֶל יהוה כָּל אַפְסֵי אָרֶץ, וְיִשְׁתַּחֲווּ לְפָנֶיךָ כָּל מִשְׁפְּחוֹת גּוֹיִם: כִּי לַיהוה הַמְּלוּכָה, וּמֹשֵׁל בַּגּוֹיִם: אָכְלוּ וַיִּשְׁתַּחֲוּוּ כָּל דִּשְׁנֵי אֶרֶץ, לְפָנָיו יִכְרְעוּ כָּל יוֹרְדֵי עָפָר, וְנַפְשׁוֹ לֹא חִיָּה: זֶרַע יַעַבְדֶנּוּ, יְסֻפַּר לַאדֹנָי לַדּוֹר: יָבֹאוּ וְיַגִּידוּ צִדְקָתוֹ, לְעַם נוֹלָד כִּי עָשָׂה:","cond":["musaf","ester"]},{"kind":"special","text":"מזמור לחנוכה:","cond":["musaf","chanuka"]},{"kind":"text","text":"מִזְמוֹר שִׁיר חֲנֻכַּת הַבַּיִת לְדָוִד: אֲרוֹמִמְךָ יהוה כִּי דִלִּיתָנִי, וְלֹא שִׂמַּחְתָּ אֹיְבַי לִי: יהוה אֱלֹהָי שִׁוַּעְתִּי אֵלֶיךָ וַתִּרְפָּאֵנִי: יהוה, הֶעֱלִיתָ מִן שְׁאוֹל נַפְשִׁי, חִיִּיתַנִי מִיָּרְדִי בוֹר: זַמְּרוּ לַיהוה חֲסִידָיו וְהוֹדוּ לְזֵכֶר קָדְשׁוֹ: כִּי רֶגַע בְּאַפּוֹ חַיִּים בִּרְצוֹנוֹ, בָּעֶרֶב יָלִין בֶּכִי וְלַבֹּקֶר רִנָּה: וַאֲנִי אָמַרְתִּי בְשַׁלְוִי בַּל אֶמּוֹט לְעוֹלָם: יהוה בִּרְצוֹנְךָ הֶעֱמַדְתָּה לְהַרְרִי עֹז, הִסְתַּרְתָּ פָנֶיךָ הָיִיתִי נִבְהָל: אֵלֶיךָ יהוה אֶקְרָא וְאֶל אֲדֹנָי אֶתְחַנָּן: מַה בֶּצַע בְּדָמִי בְּרִדְתִּי אֶל שָׁחַת, הֲיוֹדְךָ עָפָר הֲיַגִּיד אֲמִתֶּךָ: שְׁמַע יהוה וְחָנֵּנִי, יהוה הֱיֵה עֹזֵר לִי: הָפַכְתָּ מִסְפְּדִי לְמָחוֹל לִי, פִּתַּחְתָּ שַׂקִּי וַתְּאַזְּרֵנִי שִׂמְחָה: לְמַעַן יְזַמֶּרְךָ כָבוֹד וְלֹא יִדֹּם, יהוה אֱלֹהַי לְעוֹלָם אוֹדֶךָּ:","cond":["musaf","chanuka"]},{"kind":"header","text":"הכנסת ספר תורה","cond":["tora"]},{"kind":"instruction","text":"הכנסת ספר תורה","cond":["tora"]},{"kind":"text","text":"יְהַלְלוּ אֶת שֵׁם יהוה כִּי נִשְׂגָּב שְׁמוֹ לְבַדּוֹ, הוֹדוֹ עַל אֶרֶץ וְשָׁמָיִם: וַיָּרֶם קֶרֶן לְעַמּוֹ, תְּהִלָּה לְכָל חֲסִידָיו, לִבְנֵי יִשְׂרָאֵל עַם קְרֹבוֹ, הַלְלוּיָהּ: יהוה הוּא הָאֱלֹהִים. יהוה הוּא הָאֱלֹהִים בַּשָּׁמַיִם מִמַּעַל וְעַל הָאָרֶץ מִתָּחַת, אֵין עוֹד: אֵין כָּמוֹךָ בָאֱלֹהִים, אֲדֹנָי, וְאֵין כְּמַעֲשֶׂיךָ: הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם:","cond":["tora"]},{"kind":"instruction","text":"חצי קדיש","cond":["musaf"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["musaf"]},{"kind":"header","text":"מוסף","cond":["musaf"]},{"kind":"instruction","text":"לפני תפילת העמידה חולצים את התפילין.","cond":["musaf","rh"]},{"kind":"instruction","text":"תפילת העמידה","cond":["musaf"]},{"kind":"text","text":"אֲדֹנָי, שְׂפָתַי תִּפְתָּח, וּפִי יַגִּיד תְּהִלָּתֶךָ:","cond":["musaf"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יְהֹוָה, אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק וֵאלֹהֵי יַעֲקֹב, הָאֵל הַגָּדוֹל, הַגִּבּוֹר וְהַנּוֹרָא, אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, קוֹנֵה הַכֹּל וְזוֹכֵר חַסְדֵי אָבוֹת וּמֵבִיא גּוֹאֵל לִבְנֵי בְנֵיהֶם לְמַעַן שְׁמוֹ בְּאַהֲבָה.","cond":["musaf"]},{"kind":"special","text":"זָכְרֵנוּ לְחַיִּים, מֶלֶךְ חָפֵץ בַּחַיִּים, כָּתְבֵנוּ בְּסֵפֶר חַיִּים, לְמַעַנְךָ אֱלֹהִים חַיִּים.","cond":["musaf","ayt"]},{"kind":"text","text":"מֶלֶךְ עוֹזֵר וּמוֹשִׁיעַ וּמָגֵן. בָּרוּךְ אַתָּה יַהַוַהַ, מָגֵן אַבְרָהָם.","cond":["musaf"]},{"kind":"text","text":"אַתָּה גִּבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֵּה מֵתִים אַתָּה, רַב לְהוֹשִׁיעַ,","cond":["musaf"]},{"kind":"summer","text":"מוֹרִיד הַטָּל,","cond":["musaf","summerTal"]},{"kind":"winter","text":"מַשִּׁיב הָרוּחַ וּמוֹרִיד הַגֶּשֶׁם,","cond":["musaf","winterTal"]},{"kind":"text","text":"מְכַלְכֵּל חַיִּים בְּחֶסֶד, מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים, סוֹמֵךְ נוֹפְלִים וְרוֹפֵא חוֹלִים, וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמוּנָתוֹ לִישֵׁנֵי עָפָר. מי כָמוֹךָ בַּעַל גְּבוּרוֹת וּמִי דוֹמֶה לָךְ, מֶלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִיחַ יְשׁוּעָה.","cond":["musaf"]},{"kind":"special","text":"מִי כָמוֹךָ אַב הָרַחֲמָן, זוֹכֵר יְצוּרָיו בְּרַחֲמִים לְחַיִּים.","cond":["musaf","ayt"]},{"kind":"text","text":"וְנֶאֱמָן אַתָּה לְהַחֲיוֹת מֵתִים. בָּרוּךְ אַתָּה יֵהֵוֵהֵ, מְחַיֵּה הַמֵּתִים.","cond":["musaf"]},{"kind":"text","text":"אַתָּה קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ, וּקְדוֹשִׁים בְּכָל-יוֹם יְהַלְלוּךָ סֶּלָה.","cond":["musaf"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יֹהֵוָה, הַמֶּלֶךְ הַקָּדוֹשׁ.","cond":["musaf","ayt"]},{"kind":"text","text":"בּרוּךְ אַתָּה יֹהֵוָה, הָאֵל הַקָּדוֹשׁ.","cond":["musaf","noayt"]},{"kind":"text","text":"רָאשֵׁי חֳדָשִׁים לְעַמְּךָ נָתָתָּ, זְמַן כַּפָּרָה לְכָל תּוֹלְדוֹתָם, בִּהְיוֹתָם מַקְרִיבִים לְפָנֶיךָ זִבְחֵי רָצוֹן, וּשְׂעִיר חַטָּאת לְכַפֵּר בַּעֲדָם. זִכָּרוֹן לְכֻלָּם הָיָה, תְּשׁוּעַת נַפְשָׁם מִיַּד שׂוֹנֵא. מִזְבֵּחַ חָדָשׁ בְּצִיּוֹן תָּכִין, וְעוֹלַת רֹאשׁ חֹדֶשׁ נַעֲלֶה עָלָיו, וּשְׂעִיר עִזִּים נַעֲשֶׂה בְרָצוֹן, וּבַעֲבוֹדַת בֵּית הַמִּקְדָּשׁ נִשְׂמַח כֻּלָּנוּ, וְשִׁירֵי דָּוִד עַבְדָּךְ נִשְׁמַע בְּעִירָךְ, אֲמוּרִים לִפְנֵי מִזְבָּחָךְ. אַהֲבַת עולָם תָּבִיא לָהֶם וּבְרִית אָבוֹת לַבָּנִים תִּזְכּוֹר.\n\nיְהִי רָצוֹן מִלְּפָנֶיךָ, יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתַּעֲלֵנוּ בְשִׂמְחָה לְאַרְצֵנוּ, וְתִטָּעֵנוּ בִּגְבוּלֵנוּ, וְשָׁם נַעֲשֶׂה לְפָנֶיךָ אֶת קָרְבְּנוֹת חוֹבוֹתֵינוּ, תְּמִידִים כְּסִדְרָם וּמוּסָפִים כְּהִלְכָתָם. אֶת מוּסַף יוֹם רֹאשׁ חֹדֶשׁ הַזֶּה, נַעֲשֶׂה וְנַקְרִיב לְפָנֶיךָ בְּאַהֲבָה כְּמִצְוַת רְצוֹנָךְ, כְּמוֹ שֶׁכָּתַבְתָּ עָלֵינוּ בְּתוֹרָתָךְ, עַל יְדֵי מֹשֶׁה עַבְדָּךְ מִפִּי כְבוֹדֶךָ, כָּאָמוּר:\nוּבְרָאשֵׁי חָדְשֵׁיכֶם תַּקְרִיבוּ עֹלָה לַיהוה, פָּרִים בְּנֵי בָקָר שְׁנַיִם וְאַיִל אֶחָד, כְּבָשִׂים בְּנֵי שָׁנָה שִׁבְעָה, תְּמִימִם:\nוּמִנְחָתָם וְנִסְכֵּיהֶם כִּמְדֻבָּר: שְׁלֹשָׁה עֶשְׂרֹנִים לַפָּר, וּשְׁנֵי עֶשְׂרֹנִים לָאָיִל, וְעִשָּׂרֹן לַכֶּבֶשׂ, וְיַיִן כְּנִסְכּוֹ, וְשָׂעִיר לְכַפֵּר, וּשְׁנֵי תְמִידִים כְּהִלְכָתָם.\n\nאֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, חַדֵּשׁ עָלֵינוּ אֶת הַחֹדֶשׁ הַזֶּה לְטוֹבָה וְלִבְרָכָה, לְשָׂשׂוֹן וּלְשִׂמְחָה, לִישׁוּעָה וּלְנֶחָמָה, לְפַרְנָסָה וּלְכַלְכָּלָה, לְחַיִּים טוֹבִים וּלְשָׁלוֹם, לִמְחִילַת חֵטְא וְלִסְלִיחַת עָווֹן.","cond":["musaf","rh"]},{"kind":"text","text":"וּלְכַפָּרַת פֶּשַׁע.","cond":["musaf","rh","leap"]},{"kind":"text","text":"וְיִהְיֶה רֹאשׁ הַחֹדֶשׁ הַזֶּה סוֹף וָקֵץ לְכָל צָרוֹתֵינוּ, תְּחִלָּה וָרֹאשׁ לְפִדְיוֹן נַפְשֵׁנוּ. כִּי בְעַמְּךָ יִשְׂרָאֵל מִכָּל הָאֻמּוֹת בָּחָרְתָּ, וְחֻקֵּי רָאשֵׁי חֳדָשִׁים לָהֶם קָבָעְתָּ. בָּרוּךְ אַתָּה יהוה, מְקַדֵּשׁ יִשְׂרָאֵל וְרָאשֵׁי חֳדָשִׁים.","cond":["musaf","rh"]},{"kind":"text","text":"אַתָּה בְּחַרְתָּנוּ מִכָּל הָעַמִּים, אָהַבְתָּ אוֹתָנוּ וְרָצִיתָ בָּנוּ וְרוֹמַמְתָּנוּ מִכָּל הַלְּשׁוֹנוֹת וְקִדַּשְׁתָּנוּ בְּמִצְוׂתֶיךָ, וְקֵרַבְתָּנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶךָ וְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ עָלֵינוּ קָרָאתָ.\nוַתִּתֶּן לָנוּ יהוה אֱלֹהֵינוּ בְּאַהֲבָה מוֹעֲדִים לְשִׂמְחָה, חַגִּים וּזְמַנִּים לְשָׂשׂוֹן, אֶת יוֹם","cond":["musaf","sucot"]},{"kind":"text","text":"חַג הַמַּצּוֹת הַזֶּה, אֶת יוֹם מִקְרָא קֹדֶשׁ הַזֶּה, זְמַן חֵרוּתֵנוּ","cond":["musaf","sucot","pesach"]},{"kind":"text","text":"חַג הַסֻּכּוֹת הַזֶּה, אֶת יוֹם מִקְרָא קֹדֶשׁ הַזֶּה, זְמַן שִׂמְחָתֵנוּ","cond":["musaf","sucot","sucot"]},{"kind":"text","text":"בְּאַהֲבָה מִקְרָא קֹדֶשׁ זֵכֶר לִיצִיאַת מִצְרָיִם.\n\nאֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מִפְּנֵי חֲטָאֵינוּ גָּלִינוּ מֵאַרְצֵנוּ וְנִתְרַחַקְנוּ מֵעַל אַדְמָתֵנוּ, וְאֵין אֲנַחְנוּ יְכוֹלִים לַעֲלוֹת וְלֵרָאוֹת וּלְהִשְׁתַּחֲווֹת לְפָנֶיךָ בְּבֵית בְּחִירָתָךְ בִּנְוֵה הֲדָרָךְ, בַּבַּיִת הַגָּדוֹל וְהַקָּדוֹשׁ שֶׁנִּקְרָא שִׁמְךָ עָלָיו, מִפְּנֵי הַיָּד שֶׁנִּשְׁתַּלְּחָה בְּמִקְדָּשָׁךְ.\nיְהִי רָצוֹן מִלְּפָנֶיךָ, יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן, שֶׁתָּשׁוּב וּתְרַחֵם עָלֵינוּ וְעַל מִקְדָּשְׁךָ בְּרַחֲמֶיךָ הָרַבִּים, וְתִבְנֵהוּ מְהֵרָה וּתְגַדֵּל כְּבוֹדוֹ. אָבִינוּ מַלְכֵּנוּ אֱלֹהֵינוּ, גַּלֵּה כְבוֹד מַלְכוּתְךָ עָלֵינוּ מְהֵרָה, וְהוֹפַע וְהִנָּשֵׂא עָלֵינוּ לְעֵינֵי כָל חָי, וְקָרֵב פְּזוּרֵינוּ מִבֵּין הַגּוֹיִם, וּנְפוּצוֹתֵינוּ כַּנֵּס מִיַּרְכְּתֵי אָרֶץ. וַהֲבִיאֵנוּ יהוה אֱלֹהֵינוּ לְצִיּוֹן עִירְךָ בְּרִנָּה, וְלִירוּשָׁלַיִם עִיר מִקְדָּשְׁךָ בְּשִׂמְחַת עוֹלָם, אָנָּא אֱלֹהֵינוּ. וְשָׁם נַעֲשֶׂה לְפָנֶיךָ אֶת קָרְבְּנוֹת חוֹבוֹתֵינוּ, תְּמִידִים כְּסִדְרָם וּמוּסָפִים כְּהִלְכָתָם, אֶת מוּסַף יוֹם","cond":["musaf","sucot"]},{"kind":"text","text":"חַג הַמַּצּוֹת הַזֶּה","cond":["musaf","sucot","pesach"]},{"kind":"text","text":"חַג הַסֻּכּוֹת הַזֶּה","cond":["musaf","sucot","sucot"]},{"kind":"text","text":"יוֹם מִקְרָא קֹדֶשׁ הַזֶּה, נַעֲשֶׂה וְנַקְרִיב לְפָנֶיךָ בְּאַהֲבָה כְּמִצְוַת רְצוֹנָךְ, כְּמוֹ שֶׁכָּתַבְתָּ עָלֵינוּ בְּתוֹרָתָךְ, עַל יְדֵי מֹשֶׁה עַבְדֶּךָ.\n\nאֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן רַחֵם עָלֵינוּ, טוֹב וּמֵטִיב הִדָּרֶשׁ לָנוּ, שׁוּבָה עָלֵינוּ בַּהֲמוֹן רַחֲמֶיךָ בִּגְלַל אָבוֹת שֶׁעָשׂוּ רְצוֹנֶךָ, בְּנֵה בֵיתְךָ כְּבַתְּחִלָּה, כּונֵן בֵּית מִקְדָּשְׁךָ עַל מְכוֹנוֹ, הַרְאֵנוּ בְּבִנְיָנוֹ, שַׂמְּחֵנוּ בְּתִקּוּנוֹ, וְהָשֵׁב שְׁכִינָתְךָ לְתוֹכוֹ, וְהָשֵׁב כֹּהֲנִים לַעֲבוֹדָתָם וּלְוִיִּם לְשִׁירָם וּלְזִמְרָם, וְהָשֵׁב יִשְׂרָאֵל לִנְוֵיהֶם. וְשָׁם נַעֲלֶה וְנֵרָאֶה וְנִשְׁתַּחֲוֶה לְפָנֶיךָ בְּשָׁלֹשׁ פַּעֲמֵי רְגָלֵינוּ בְּכָל שָׁנָה וְשָׁנָה, כַּכָּתוּב בַּתּורָה: שָׁלֹשׁ פְּעָמִים בַּשָּׁנָה יֵרָאֶה כָל זְכוּרְךָ אֶת פְּנֵי יהוה אֱלֹהֶיךָ בַּמָּקום אֲשֶׁר יִבְחָר, בְּחַג הַמַּצּוֹת, וּבְחַג הַשָּׁבֻעוֹת, וּבְחַג הַסֻּכּוֹת, וְלא יֵרָאֶה אֶת פְּנֵי יהוה רֵיקָם: אִישׁ כְּמַתְּנַת יָדוֹ, כְּבִרְכַּת יהוה אֱלֹהֶיךָ אֲשֶׁר נָתַן לָךְ:\n\nוְהַשִּׂיאֵנוּ יהוה אֱלֹהֵינוּ אֶת בִּרְכַּת מוֹעֲדֶיךָ לְחַיִּים בְּשִׂמְחָה וּבְשָׁלוֹם, כַּאֲשֶׁר רָצִיתָ וְאָמַרְתָּ לְבָרְכֵנוּ, כֵּן תְּבָרְכֵנוּ סֶלָה. קַדְּשֵׁנוּ בְּמִצְוׂתֶיךָ, שִׂים חֶלְקֵנוּ בְּתוֹרָתָךְ, שַׂבְּעֵנוּ מִטּוּבָךְ, שַׂמֵּחַ נַפְשֵׁנוּ בִּישׁוּעָתָךְ, וְטַהֵר לִבֵּנוּ לְעָבְדְּךָ בֶאֱמֶת. וְהַנְחִילֵנוּ יהוה אֱלֹהֵינוּ בְּשִׂמְחָה וּבְשָׂשׂוֹן מוֹעֲדֵי קָדְשֶׁךָ, וְיִשְׂמְחוּ בְךָ כָּל יִשְׂרָאֵל מְקַדְּשֵׁי שְׁמֶךָ. בָּרוּךְ אַתָּה יהוה, מְקַדֵּשׁ יִשְׂרָאֵל וְהַזְּמַנִּים.","cond":["musaf","sucot"]},{"kind":"text","text":"אַתָּה בְּחַרְתָּנוּ מִכָּל הָעַמִּים, אָהַבְתָּ אוֹתָנוּ וְרָצִיתָ בָּנוּ וְרוֹמַמְתָּנוּ מִכָּל הַלְּשׁוֹנוֹת וְקִדַּשְׁתָּנוּ בְּמִצְוׂתֶיךָ, וְקֵרַבְתָּנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶךָ וְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ עָלֵינוּ קָרָאתָ.\nוַתִּתֶּן לָנוּ יהוה אֱלֹהֵינוּ בְּאַהֲבָה מוֹעֲדִים לְשִׂמְחָה, חַגִּים וּזְמַנִּים לְשָׂשׂוֹן, אֶת יוֹם","cond":["musaf","pesach"]},{"kind":"text","text":"חַג הַמַּצּוֹת הַזֶּה, אֶת יוֹם מִקְרָא קֹדֶשׁ הַזֶּה, זְמַן חֵרוּתֵנוּ","cond":["musaf","pesach","pesach"]},{"kind":"text","text":"חַג הַסֻּכּוֹת הַזֶּה, אֶת יוֹם מִקְרָא קֹדֶשׁ הַזֶּה, זְמַן שִׂמְחָתֵנוּ","cond":["musaf","pesach","sucot"]},{"kind":"text","text":"בְּאַהֲבָה מִקְרָא קֹדֶשׁ זֵכֶר לִיצִיאַת מִצְרָיִם.\n\nאֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מִפְּנֵי חֲטָאֵינוּ גָּלִינוּ מֵאַרְצֵנוּ וְנִתְרַחַקְנוּ מֵעַל אַדְמָתֵנוּ, וְאֵין אֲנַחְנוּ יְכוֹלִים לַעֲלוֹת וְלֵרָאוֹת וּלְהִשְׁתַּחֲווֹת לְפָנֶיךָ בְּבֵית בְּחִירָתָךְ בִּנְוֵה הֲדָרָךְ, בַּבַּיִת הַגָּדוֹל וְהַקָּדוֹשׁ שֶׁנִּקְרָא שִׁמְךָ עָלָיו, מִפְּנֵי הַיָּד שֶׁנִּשְׁתַּלְּחָה בְּמִקְדָּשָׁךְ.\nיְהִי רָצוֹן מִלְּפָנֶיךָ, יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן, שֶׁתָּשׁוּב וּתְרַחֵם עָלֵינוּ וְעַל מִקְדָּשְׁךָ בְּרַחֲמֶיךָ הָרַבִּים, וְתִבְנֵהוּ מְהֵרָה וּתְגַדֵּל כְּבוֹדוֹ. אָבִינוּ מַלְכֵּנוּ אֱלֹהֵינוּ, גַּלֵּה כְבוֹד מַלְכוּתְךָ עָלֵינוּ מְהֵרָה, וְהוֹפַע וְהִנָּשֵׂא עָלֵינוּ לְעֵינֵי כָל חָי, וְקָרֵב פְּזוּרֵינוּ מִבֵּין הַגּוֹיִם, וּנְפוּצוֹתֵינוּ כַּנֵּס מִיַּרְכְּתֵי אָרֶץ. וַהֲבִיאֵנוּ יהוה אֱלֹהֵינוּ לְצִיּוֹן עִירְךָ בְּרִנָּה, וְלִירוּשָׁלַיִם עִיר מִקְדָּשְׁךָ בְּשִׂמְחַת עוֹלָם, אָנָּא אֱלֹהֵינוּ. וְשָׁם נַעֲשֶׂה לְפָנֶיךָ אֶת קָרְבְּנוֹת חוֹבוֹתֵינוּ, תְּמִידִים כְּסִדְרָם וּמוּסָפִים כְּהִלְכָתָם, אֶת מוּסַף יוֹם","cond":["musaf","pesach"]},{"kind":"text","text":"חַג הַמַּצּוֹת הַזֶּה","cond":["musaf","pesach","pesach"]},{"kind":"text","text":"חַג הַסֻּכּוֹת הַזֶּה","cond":["musaf","pesach","sucot"]},{"kind":"text","text":"יוֹם מִקְרָא קֹדֶשׁ הַזֶּה, נַעֲשֶׂה וְנַקְרִיב לְפָנֶיךָ בְּאַהֲבָה כְּמִצְוַת רְצוֹנָךְ, כְּמוֹ שֶׁכָּתַבְתָּ עָלֵינוּ בְּתוֹרָתָךְ, עַל יְדֵי מֹשֶׁה עַבְדֶּךָ.\n\nאֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן רַחֵם עָלֵינוּ, טוֹב וּמֵטִיב הִדָּרֶשׁ לָנוּ, שׁוּבָה עָלֵינוּ בַּהֲמוֹן רַחֲמֶיךָ בִּגְלַל אָבוֹת שֶׁעָשׂוּ רְצוֹנֶךָ, בְּנֵה בֵיתְךָ כְּבַתְּחִלָּה, כּונֵן בֵּית מִקְדָּשְׁךָ עַל מְכוֹנוֹ, הַרְאֵנוּ בְּבִנְיָנוֹ, שַׂמְּחֵנוּ בְּתִקּוּנוֹ, וְהָשֵׁב שְׁכִינָתְךָ לְתוֹכוֹ, וְהָשֵׁב כֹּהֲנִים לַעֲבוֹדָתָם וּלְוִיִּם לְשִׁירָם וּלְזִמְרָם, וְהָשֵׁב יִשְׂרָאֵל לִנְוֵיהֶם. וְשָׁם נַעֲלֶה וְנֵרָאֶה וְנִשְׁתַּחֲוֶה לְפָנֶיךָ בְּשָׁלֹשׁ פַּעֲמֵי רְגָלֵינוּ בְּכָל שָׁנָה וְשָׁנָה, כַּכָּתוּב בַּתּורָה: שָׁלֹשׁ פְּעָמִים בַּשָּׁנָה יֵרָאֶה כָל זְכוּרְךָ אֶת פְּנֵי יהוה אֱלֹהֶיךָ בַּמָּקום אֲשֶׁר יִבְחָר, בְּחַג הַמַּצּוֹת, וּבְחַג הַשָּׁבֻעוֹת, וּבְחַג הַסֻּכּוֹת, וְלא יֵרָאֶה אֶת פְּנֵי יהוה רֵיקָם: אִישׁ כְּמַתְּנַת יָדוֹ, כְּבִרְכַּת יהוה אֱלֹהֶיךָ אֲשֶׁר נָתַן לָךְ:\n\nוְהַשִּׂיאֵנוּ יהוה אֱלֹהֵינוּ אֶת בִּרְכַּת מוֹעֲדֶיךָ לְחַיִּים בְּשִׂמְחָה וּבְשָׁלוֹם, כַּאֲשֶׁר רָצִיתָ וְאָמַרְתָּ לְבָרְכֵנוּ, כֵּן תְּבָרְכֵנוּ סֶלָה. קַדְּשֵׁנוּ בְּמִצְוׂתֶיךָ, שִׂים חֶלְקֵנוּ בְּתוֹרָתָךְ, שַׂבְּעֵנוּ מִטּוּבָךְ, שַׂמֵּחַ נַפְשֵׁנוּ בִּישׁוּעָתָךְ, וְטַהֵר לִבֵּנוּ לְעָבְדְּךָ בֶאֱמֶת. וְהַנְחִילֵנוּ יהוה אֱלֹהֵינוּ בְּשִׂמְחָה וּבְשָׂשׂוֹן מוֹעֲדֵי קָדְשֶׁךָ, וְיִשְׂמְחוּ בְךָ כָּל יִשְׂרָאֵל מְקַדְּשֵׁי שְׁמֶךָ. בָּרוּךְ אַתָּה יהוה, מְקַדֵּשׁ יִשְׂרָאֵל וְהַזְּמַנִּים.","cond":["musaf","pesach"]},{"kind":"text","text":"רְצֵה יְהֹוָה אֱלֹהֵינוּ בְּעַמְּךָ יִשְׂרָאֵל, וּלִתְפִלָּתָם שְׁעֵה, וְהָשֵׁב הָעֲבוֹדָה לִדְבִיר בֵּיתֶךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם מְהֵרָה בְאַהֲבָה תְּקַבֵּל בְּרָצוֹן, וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּךָ. וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים תַּחְפֹּץ בָּנוּ וְתִרְצֵנוּ, וְתֶחֱזֶינָה עֵינֵינוּ בְּשׁוּבְךָ לְצִיּוֹן בְּרַחֲמִים. בָּרוּךְ אַתָּה יִהִוִהִ, הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן.","cond":["musaf"]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שֶׁאַתָּה הוּא יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ לְעוֹלָם וָעֶד, צוּרֵנוּ צוּר חַיֵּינוּ וּמָגֵן יִשְׁעֵנוּ אַתָּה הוּא לְדֹר וָדֹר. נוֹדֶה לְּךָ וּנְסַפֵּר תְּהִלָּתֶךָ, עַל חַיֵּינוּ הַמְּסוּרִים בְּיָדֶךָ, וְעַל נִשְׁמוֹתֵינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּיךָ שֶׁבְּכָל יוֹם עִמָּנוּ, וְעַל נִפְלְאוֹתֶיךָ וְטוֹבוֹתֶיךָ שֶׁבְּכָל עֵת, עֶרֶב וָבֹקֶר וְצָהֳרָיִם. הַטּוֹב, כִּי לֹא כָלוּ רַחֲמֶיךָ, הַמְרַחֵם, כִּי לֹא תַמּוּ חֲסָדֶיךָ, כִּי מֵעוֹלָם קִוִּינוּ לָךְ.","cond":["musaf"]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת, שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה, בִּימֵי מַתִּתְיָה בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְשַׁכְּחָם תּוֹרָתָךְ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנָךְ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וּטְמֵאִים בְּיַד טְהוֹרִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, לְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמָךְ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כָּךְ בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ בְּהַלֵּל גָּמוּר וּבְהוֹדָאָה, וְעָשִׂיתָ עִמָּהֶם נִסִּים וְנִפְלָאוֹת, וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל, סֶלָה.","cond":["musaf","chanuka"]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת, שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה, בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים, בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ, וְעָשִׂיתָ עִמָּהֶם נִסִּים וְנִפְלָאוֹת, וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל, סֶלָה.","cond":["musaf","purim"]},{"kind":"text","text":"וְעַל כֻּלָּם יִתְבָּרַךְ וְיִתְרוֹמַם וְיִתְנַשֵּׂא תָמִיד, שִׁמְךָ מַלְכֵּנוּ, לְעוֹלָם וָעֶד. וְכָל הַחַיִּים יוֹדוּךָ סֶּלָה.","cond":["musaf"]},{"kind":"special","text":"וּכְתֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶךָ.","cond":["musaf","ayt"]},{"kind":"text","text":"וִיהַלְלוּ וִיבָרְכוּ אֶת שִׁמְךָ הַגָּדוֹל, בֶּאֱמֶת, לְעוֹלָם כִּי טוֹב, הָאֵל יְשׁוּעָתֵנוּ וְעֶזְרָתֵנוּ סֶלָה, הָאֵל הַטּוֹב. בָּרוּךְ אַתָּה יֻהֻוֻהֻ, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת.","cond":["musaf"]},{"kind":"text","text":"שִׂים שָׁלוֹם טוֹבָה וּבְרָכָה, חַיִּים, חֵן וָחֶסֶד, צְדָקָה וְרַחֲמִים, עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל עַמֶּךָ. וּבָרְכֵנוּ אָבִינוּ, כֻּלָּנוּ כְאֶחָד בְּאוֹר פָּנֶיךָ, כִּי בְאוֹר פָּנֶיךָ נָתַתָּ לָּנוּ יְהֹוָה אֱלֹהֵינוּ, תּוֹרָה וְחַיִּים, אַהֲבָה וָחֶסֶד, צְדָקָה וְרַחֲמִים, בְּרָכָה וְשָׁלוֹם. וְטוֹב בְּעֵינֶיךָ לְבָרְכֵנוּ וּלְבָרֵךְ אֶת כָּל עַמְּךָ יִשְׂרָאֵל בְּרֹב עֹז וְשָׁלוֹם.","cond":["musaf"]},{"kind":"special","text":"וּבְסֵפֶר חֵיִּים, בְּרָכָה וְשָׁלוֹם, וּפַרְנָסָה טוֹבָה וִישׁוּעָה וְנֶחָמָה, וּגְזֵרוֹת טוֹבוֹת, נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ, אֲנַחְנוּ וְכָל עַמְּךָ יִשְׂרָאֵל, לְחַיִּים טוֹבִים וּלְשָׁלוֹם.","cond":["musaf","ayt"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יוּהוּווּהוּ, הַמְּבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם. אָמֵן.","cond":["musaf"]},{"kind":"text","text":"יִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:\nאֱלֹהַי, נְצֹר לְשׁוֹנִי מֵרָע, וּשְׂפָתַי מִדַּבֵּר מִרְמָה, וְלִמְקַלְלַי נַפְשִׁי תִדֹּם, וְנַפְשִׁי כֶּעָפָר לַכֹּל תִּהְיֶה. פְּתַח לִבִּי בְּתוֹרָתֶךָ, וְאַחֲרֵי מִצְוׂתֶיךָ תִּרְדֹּף נַפְשִׁי. וְכָל הַקָּמִים עָלַי לְרָעָה, מְהֵרָה הָפֵר עֲצָתָם וְקַלְקֵל מַחְשְבוֹתָם. (יִהְיוּ כְּמֹץ לִפְנֵי רוּחַ, וּמַלְאַךְ יהוה דּוֹחֶה.) עֲשֵׂה לְמַעַן שְׁמָךְ, עֲשֵׂה לְמַעַן יְמִינָךְ, עֲשֵׂה לְמַעַן תּוֹרָתָךְ, עֲשֵׂה לְמַעַן קְדֻשָּׁתָךְ, לְמַעַן יֵחָלְצוּן יְדִידֶיךָ. הוֹשִׁיעָה יְמִינְךָ וַעֲנֵנִי.\nיִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:","cond":["musaf"]},{"kind":"instruction","text":"יש נוהגים לומר כאן תחנונים, ויש אומרים תפילה זו:\nיְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁלֹּא תַעֲלֶה קִנְאַת אֲחֵרִים עָלַי וְלֹא קִנְאָתִי עַל אֲחֵרִים, וְשֶׁלֹּא אֶכְעוֹס הַיּוֹם וְשֶׁלֹּא אַכְעִיסֶך, וְתַצִּילֵנִי מִיֵּצֶר הָרָע, וְתֵן בְּלִבִּי הַכְנָעָה וַעֲנָוָה וְיִרְאַת חֵטְא. מַלְכֵּנוּ וֵאלֹהֵינוּ, יַחֵד שִׁמְךָ בְּעוֹלָמָךְ וּבְנֵה בֵיתָךְ, שַׁכְלֵל הֵיכָלָךְ וְקַבֵּץ גָּלֻיּוֹתֵינוּ, פְּדֵה צֹאנָךְ וְשַמַּח עֲדָתָךְ בִּמְהֵרָה בְיָמֵינוּ וְתֵן חֶלְקֵנוּ בְּתוֹרָתָךְ. אָמֵן.","cond":["musaf"]},{"kind":"text","text":"עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["musaf","noayt"]},{"kind":"special","text":"עֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["musaf","ayt"]},{"kind":"text","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּבְנֶה בֵית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵינוּ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתָךְ לַעֲשׂוֹת חֻקֵּי רְצוֹנָךְ וּלְעָבְדָךְ בְּלֵבָב שָׁלֵם.","cond":["musaf"]},{"kind":"header","text":"חזרת הש\"ץ","cond":["musaf"]},{"kind":"instruction","text":"חזרת הש\"ץ","cond":["musaf"]},{"kind":"text","text":"אֲדֹנָי, שְׂפָתַי תִּפְתָּח, וּפִי יַגִּיד תְּהִלָּתֶךָ:","cond":["musaf"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יְהֹוָה, אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק וֵאלֹהֵי יַעֲקֹב, הָאֵל הַגָּדוֹל, הַגִּבּוֹר וְהַנּוֹרָא, אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, קוֹנֵה הַכֹּל וְזוֹכֵר חַסְדֵי אָבוֹת וּמֵבִיא גּוֹאֵל לִבְנֵי בְנֵיהֶם לְמַעַן שְׁמוֹ בְּאַהֲבָה.","cond":["musaf"]},{"kind":"special","text":"זָכְרֵנוּ לְחַיִּים, מֶלֶךְ חָפֵץ בַּחַיִּים, כָּתְבֵנוּ בְּסֵפֶר חַיִּים, לְמַעַנְךָ אֱלֹהִים חַיִּים.","cond":["musaf","ayt"]},{"kind":"text","text":"מֶלֶךְ עוֹזֵר וּמוֹשִׁיעַ וּמָגֵן. בָּרוּךְ אַתָּה יַהַוַהַ, מָגֵן אַבְרָהָם.","cond":["musaf"]},{"kind":"text","text":"אַתָּה גִּבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֵּה מֵתִים אַתָּה, רַב לְהוֹשִׁיעַ,","cond":["musaf"]},{"kind":"summer","text":"מוֹרִיד הַטָּל,","cond":["musaf","summerTal"]},{"kind":"winter","text":"מַשִּׁיב הָרוּחַ וּמוֹרִיד הַגֶּשֶׁם,","cond":["musaf","winterTal"]},{"kind":"text","text":"מְכַלְכֵּל חַיִּים בְּחֶסֶד, מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים, סוֹמֵךְ נוֹפְלִים וְרוֹפֵא חוֹלִים, וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמוּנָתוֹ לִישֵׁנֵי עָפָר. מי כָמוֹךָ בַּעַל גְּבוּרוֹת וּמִי דוֹמֶה לָךְ, מֶלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִיחַ יְשׁוּעָה.","cond":["musaf"]},{"kind":"special","text":"מִי כָמוֹךָ אַב הָרַחֲמָן, זוֹכֵר יְצוּרָיו בְּרַחֲמִים לְחַיִּים.","cond":["musaf","ayt"]},{"kind":"text","text":"וְנֶאֱמָן אַתָּה לְהַחֲיוֹת מֵתִים. בָּרוּךְ אַתָּה יֵהֵוֵהֵ, מְחַיֵּה הַמֵּתִים.","cond":["musaf"]},{"kind":"header","text":"קדושה","cond":["musaf"]},{"kind":"text","text":"כֶּתֶר יִתְּנוּ לְךָ יהוה אֱלֹהֵינוּ מַלְאָכִים הֲמוֹנֵי מַעְלָה. עִם עַמְּךָ יִשְׂרָאֵל קְבוּצֵי מַטָּה, יַחַד כֻּלָּם קְדֻשָּׁה לְךָ יְשַׁלֵּשׁוּ כַּדָּבָר הָאָמוּר עַל יַד נְבִיאֶךָ וְקָרָא זֶה אֶל זֶה וְאָמַר:\nקדוש קדוש קדוש יהוה צבאות. מלא כל הארץ כבודו:\nלעמתם משבחים ואומרים - ברוך כבוד יהוה ממקומו:\nובדברי קדשך כתוב לאמר - ימלך יהוה לעולם אלהיך ציון לדר ודר הללויה:","cond":["musaf"]},{"kind":"text","text":"אַתָּה קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ, וּקְדוֹשִׁים בְּכָל-יוֹם יְהַלְלוּךָ סֶּלָה.","cond":["musaf"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יֹהֵוָה, הַמֶּלֶךְ הַקָּדוֹשׁ.","cond":["musaf","ayt"]},{"kind":"text","text":"בּרוּךְ אַתָּה יֹהֵוָה, הָאֵל הַקָּדוֹשׁ.","cond":["musaf","noayt"]},{"kind":"text","text":"רָאשֵׁי חֳדָשִׁים לְעַמְּךָ נָתָתָּ, זְמַן כַּפָּרָה לְכָל תּוֹלְדוֹתָם, בִּהְיוֹתָם מַקְרִיבִים לְפָנֶיךָ זִבְחֵי רָצוֹן, וּשְׂעִיר חַטָּאת לְכַפֵּר בַּעֲדָם. זִכָּרוֹן לְכֻלָּם הָיָה, תְּשׁוּעַת נַפְשָׁם מִיַּד שׂוֹנֵא. מִזְבֵּחַ חָדָשׁ בְּצִיּוֹן תָּכִין, וְעוֹלַת רֹאשׁ חֹדֶשׁ נַעֲלֶה עָלָיו, וּשְׂעִיר עִזִּים נַעֲשֶׂה בְרָצוֹן, וּבַעֲבוֹדַת בֵּית הַמִּקְדָּשׁ נִשְׂמַח כֻּלָּנוּ, וְשִׁירֵי דָּוִד עַבְדָּךְ נִשְׁמַע בְּעִירָךְ, אֲמוּרִים לִפְנֵי מִזְבָּחָךְ. אַהֲבַת עולָם תָּבִיא לָהֶם וּבְרִית אָבוֹת לַבָּנִים תִּזְכּוֹר.\n\nיְהִי רָצוֹן מִלְּפָנֶיךָ, יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתַּעֲלֵנוּ בְשִׂמְחָה לְאַרְצֵנוּ, וְתִטָּעֵנוּ בִּגְבוּלֵנוּ, וְשָׁם נַעֲשֶׂה לְפָנֶיךָ אֶת קָרְבְּנוֹת חוֹבוֹתֵינוּ, תְּמִידִים כְּסִדְרָם וּמוּסָפִים כְּהִלְכָתָם. אֶת מוּסַף יוֹם רֹאשׁ חֹדֶשׁ הַזֶּה, נַעֲשֶׂה וְנַקְרִיב לְפָנֶיךָ בְּאַהֲבָה כְּמִצְוַת רְצוֹנָךְ, כְּמוֹ שֶׁכָּתַבְתָּ עָלֵינוּ בְּתוֹרָתָךְ, עַל יְדֵי מֹשֶׁה עַבְדָּךְ מִפִּי כְבוֹדֶךָ, כָּאָמוּר:\nוּבְרָאשֵׁי חָדְשֵׁיכֶם תַּקְרִיבוּ עֹלָה לַיהוה, פָּרִים בְּנֵי בָקָר שְׁנַיִם וְאַיִל אֶחָד, כְּבָשִׂים בְּנֵי שָׁנָה שִׁבְעָה, תְּמִימִם:\nוּמִנְחָתָם וְנִסְכֵּיהֶם כִּמְדֻבָּר: שְׁלֹשָׁה עֶשְׂרֹנִים לַפָּר, וּשְׁנֵי עֶשְׂרֹנִים לָאָיִל, וְעִשָּׂרֹן לַכֶּבֶשׂ, וְיַיִן כְּנִסְכּוֹ, וְשָׂעִיר לְכַפֵּר, וּשְׁנֵי תְמִידִים כְּהִלְכָתָם.\n\nאֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, חַדֵּשׁ עָלֵינוּ אֶת הַחֹדֶשׁ הַזֶּה לְטוֹבָה וְלִבְרָכָה, לְשָׂשׂוֹן וּלְשִׂמְחָה, לִישׁוּעָה וּלְנֶחָמָה, לְפַרְנָסָה וּלְכַלְכָּלָה, לְחַיִּים טוֹבִים וּלְשָׁלוֹם, לִמְחִילַת חֵטְא וְלִסְלִיחַת עָווֹן.","cond":["musaf","rh"]},{"kind":"text","text":"וּלְכַפָּרַת פֶּשַׁע.","cond":["musaf","rh","leap"]},{"kind":"text","text":"וְיִהְיֶה רֹאשׁ הַחֹדֶשׁ הַזֶּה סוֹף וָקֵץ לְכָל צָרוֹתֵינוּ, תְּחִלָּה וָרֹאשׁ לְפִדְיוֹן נַפְשֵׁנוּ. כִּי בְעַמְּךָ יִשְׂרָאֵל מִכָּל הָאֻמּוֹת בָּחָרְתָּ, וְחֻקֵּי רָאשֵׁי חֳדָשִׁים לָהֶם קָבָעְתָּ. בָּרוּךְ אַתָּה יהוה, מְקַדֵּשׁ יִשְׂרָאֵל וְרָאשֵׁי חֳדָשִׁים.","cond":["musaf","rh"]},{"kind":"text","text":"אַתָּה בְּחַרְתָּנוּ מִכָּל הָעַמִּים, אָהַבְתָּ אוֹתָנוּ וְרָצִיתָ בָּנוּ וְרוֹמַמְתָּנוּ מִכָּל הַלְּשׁוֹנוֹת וְקִדַּשְׁתָּנוּ בְּמִצְוׂתֶיךָ, וְקֵרַבְתָּנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶךָ וְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ עָלֵינוּ קָרָאתָ.\nוַתִּתֶּן לָנוּ יהוה אֱלֹהֵינוּ בְּאַהֲבָה מוֹעֲדִים לְשִׂמְחָה, חַגִּים וּזְמַנִּים לְשָׂשׂוֹן, אֶת יוֹם","cond":["musaf","sucot"]},{"kind":"text","text":"חַג הַמַּצּוֹת הַזֶּה, אֶת יוֹם מִקְרָא קֹדֶשׁ הַזֶּה, זְמַן חֵרוּתֵנוּ","cond":["musaf","sucot","pesach"]},{"kind":"text","text":"חַג הַסֻּכּוֹת הַזֶּה, אֶת יוֹם מִקְרָא קֹדֶשׁ הַזֶּה, זְמַן שִׂמְחָתֵנוּ","cond":["musaf","sucot","sucot"]},{"kind":"text","text":"בְּאַהֲבָה מִקְרָא קֹדֶשׁ זֵכֶר לִיצִיאַת מִצְרָיִם.\n\nאֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מִפְּנֵי חֲטָאֵינוּ גָּלִינוּ מֵאַרְצֵנוּ וְנִתְרַחַקְנוּ מֵעַל אַדְמָתֵנוּ, וְאֵין אֲנַחְנוּ יְכוֹלִים לַעֲלוֹת וְלֵרָאוֹת וּלְהִשְׁתַּחֲווֹת לְפָנֶיךָ בְּבֵית בְּחִירָתָךְ בִּנְוֵה הֲדָרָךְ, בַּבַּיִת הַגָּדוֹל וְהַקָּדוֹשׁ שֶׁנִּקְרָא שִׁמְךָ עָלָיו, מִפְּנֵי הַיָּד שֶׁנִּשְׁתַּלְּחָה בְּמִקְדָּשָׁךְ.\nיְהִי רָצוֹן מִלְּפָנֶיךָ, יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן, שֶׁתָּשׁוּב וּתְרַחֵם עָלֵינוּ וְעַל מִקְדָּשְׁךָ בְּרַחֲמֶיךָ הָרַבִּים, וְתִבְנֵהוּ מְהֵרָה וּתְגַדֵּל כְּבוֹדוֹ. אָבִינוּ מַלְכֵּנוּ אֱלֹהֵינוּ, גַּלֵּה כְבוֹד מַלְכוּתְךָ עָלֵינוּ מְהֵרָה, וְהוֹפַע וְהִנָּשֵׂא עָלֵינוּ לְעֵינֵי כָל חָי, וְקָרֵב פְּזוּרֵינוּ מִבֵּין הַגּוֹיִם, וּנְפוּצוֹתֵינוּ כַּנֵּס מִיַּרְכְּתֵי אָרֶץ. וַהֲבִיאֵנוּ יהוה אֱלֹהֵינוּ לְצִיּוֹן עִירְךָ בְּרִנָּה, וְלִירוּשָׁלַיִם עִיר מִקְדָּשְׁךָ בְּשִׂמְחַת עוֹלָם, אָנָּא אֱלֹהֵינוּ. וְשָׁם נַעֲשֶׂה לְפָנֶיךָ אֶת קָרְבְּנוֹת חוֹבוֹתֵינוּ, תְּמִידִים כְּסִדְרָם וּמוּסָפִים כְּהִלְכָתָם, אֶת מוּסַף יוֹם","cond":["musaf","sucot"]},{"kind":"text","text":"חַג הַמַּצּוֹת הַזֶּה","cond":["musaf","sucot","pesach"]},{"kind":"text","text":"חַג הַסֻּכּוֹת הַזֶּה","cond":["musaf","sucot","sucot"]},{"kind":"text","text":"יוֹם מִקְרָא קֹדֶשׁ הַזֶּה, נַעֲשֶׂה וְנַקְרִיב לְפָנֶיךָ בְּאַהֲבָה כְּמִצְוַת רְצוֹנָךְ, כְּמוֹ שֶׁכָּתַבְתָּ עָלֵינוּ בְּתוֹרָתָךְ, עַל יְדֵי מֹשֶׁה עַבְדֶּךָ.\n\nאֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן רַחֵם עָלֵינוּ, טוֹב וּמֵטִיב הִדָּרֶשׁ לָנוּ, שׁוּבָה עָלֵינוּ בַּהֲמוֹן רַחֲמֶיךָ בִּגְלַל אָבוֹת שֶׁעָשׂוּ רְצוֹנֶךָ, בְּנֵה בֵיתְךָ כְּבַתְּחִלָּה, כּונֵן בֵּית מִקְדָּשְׁךָ עַל מְכוֹנוֹ, הַרְאֵנוּ בְּבִנְיָנוֹ, שַׂמְּחֵנוּ בְּתִקּוּנוֹ, וְהָשֵׁב שְׁכִינָתְךָ לְתוֹכוֹ, וְהָשֵׁב כֹּהֲנִים לַעֲבוֹדָתָם וּלְוִיִּם לְשִׁירָם וּלְזִמְרָם, וְהָשֵׁב יִשְׂרָאֵל לִנְוֵיהֶם. וְשָׁם נַעֲלֶה וְנֵרָאֶה וְנִשְׁתַּחֲוֶה לְפָנֶיךָ בְּשָׁלֹשׁ פַּעֲמֵי רְגָלֵינוּ בְּכָל שָׁנָה וְשָׁנָה, כַּכָּתוּב בַּתּורָה: שָׁלֹשׁ פְּעָמִים בַּשָּׁנָה יֵרָאֶה כָל זְכוּרְךָ אֶת פְּנֵי יהוה אֱלֹהֶיךָ בַּמָּקום אֲשֶׁר יִבְחָר, בְּחַג הַמַּצּוֹת, וּבְחַג הַשָּׁבֻעוֹת, וּבְחַג הַסֻּכּוֹת, וְלא יֵרָאֶה אֶת פְּנֵי יהוה רֵיקָם: אִישׁ כְּמַתְּנַת יָדוֹ, כְּבִרְכַּת יהוה אֱלֹהֶיךָ אֲשֶׁר נָתַן לָךְ:\n\nוְהַשִּׂיאֵנוּ יהוה אֱלֹהֵינוּ אֶת בִּרְכַּת מוֹעֲדֶיךָ לְחַיִּים בְּשִׂמְחָה וּבְשָׁלוֹם, כַּאֲשֶׁר רָצִיתָ וְאָמַרְתָּ לְבָרְכֵנוּ, כֵּן תְּבָרְכֵנוּ סֶלָה. קַדְּשֵׁנוּ בְּמִצְוׂתֶיךָ, שִׂים חֶלְקֵנוּ בְּתוֹרָתָךְ, שַׂבְּעֵנוּ מִטּוּבָךְ, שַׂמֵּחַ נַפְשֵׁנוּ בִּישׁוּעָתָךְ, וְטַהֵר לִבֵּנוּ לְעָבְדְּךָ בֶאֱמֶת. וְהַנְחִילֵנוּ יהוה אֱלֹהֵינוּ בְּשִׂמְחָה וּבְשָׂשׂוֹן מוֹעֲדֵי קָדְשֶׁךָ, וְיִשְׂמְחוּ בְךָ כָּל יִשְׂרָאֵל מְקַדְּשֵׁי שְׁמֶךָ. בָּרוּךְ אַתָּה יהוה, מְקַדֵּשׁ יִשְׂרָאֵל וְהַזְּמַנִּים.","cond":["musaf","sucot"]},{"kind":"text","text":"אַתָּה בְּחַרְתָּנוּ מִכָּל הָעַמִּים, אָהַבְתָּ אוֹתָנוּ וְרָצִיתָ בָּנוּ וְרוֹמַמְתָּנוּ מִכָּל הַלְּשׁוֹנוֹת וְקִדַּשְׁתָּנוּ בְּמִצְוׂתֶיךָ, וְקֵרַבְתָּנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶךָ וְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ עָלֵינוּ קָרָאתָ.\nוַתִּתֶּן לָנוּ יהוה אֱלֹהֵינוּ בְּאַהֲבָה מוֹעֲדִים לְשִׂמְחָה, חַגִּים וּזְמַנִּים לְשָׂשׂוֹן, אֶת יוֹם","cond":["musaf","pesach"]},{"kind":"text","text":"חַג הַמַּצּוֹת הַזֶּה, אֶת יוֹם מִקְרָא קֹדֶשׁ הַזֶּה, זְמַן חֵרוּתֵנוּ","cond":["musaf","pesach","pesach"]},{"kind":"text","text":"חַג הַסֻּכּוֹת הַזֶּה, אֶת יוֹם מִקְרָא קֹדֶשׁ הַזֶּה, זְמַן שִׂמְחָתֵנוּ","cond":["musaf","pesach","sucot"]},{"kind":"text","text":"בְּאַהֲבָה מִקְרָא קֹדֶשׁ זֵכֶר לִיצִיאַת מִצְרָיִם.\n\nאֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מִפְּנֵי חֲטָאֵינוּ גָּלִינוּ מֵאַרְצֵנוּ וְנִתְרַחַקְנוּ מֵעַל אַדְמָתֵנוּ, וְאֵין אֲנַחְנוּ יְכוֹלִים לַעֲלוֹת וְלֵרָאוֹת וּלְהִשְׁתַּחֲווֹת לְפָנֶיךָ בְּבֵית בְּחִירָתָךְ בִּנְוֵה הֲדָרָךְ, בַּבַּיִת הַגָּדוֹל וְהַקָּדוֹשׁ שֶׁנִּקְרָא שִׁמְךָ עָלָיו, מִפְּנֵי הַיָּד שֶׁנִּשְׁתַּלְּחָה בְּמִקְדָּשָׁךְ.\nיְהִי רָצוֹן מִלְּפָנֶיךָ, יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן, שֶׁתָּשׁוּב וּתְרַחֵם עָלֵינוּ וְעַל מִקְדָּשְׁךָ בְּרַחֲמֶיךָ הָרַבִּים, וְתִבְנֵהוּ מְהֵרָה וּתְגַדֵּל כְּבוֹדוֹ. אָבִינוּ מַלְכֵּנוּ אֱלֹהֵינוּ, גַּלֵּה כְבוֹד מַלְכוּתְךָ עָלֵינוּ מְהֵרָה, וְהוֹפַע וְהִנָּשֵׂא עָלֵינוּ לְעֵינֵי כָל חָי, וְקָרֵב פְּזוּרֵינוּ מִבֵּין הַגּוֹיִם, וּנְפוּצוֹתֵינוּ כַּנֵּס מִיַּרְכְּתֵי אָרֶץ. וַהֲבִיאֵנוּ יהוה אֱלֹהֵינוּ לְצִיּוֹן עִירְךָ בְּרִנָּה, וְלִירוּשָׁלַיִם עִיר מִקְדָּשְׁךָ בְּשִׂמְחַת עוֹלָם, אָנָּא אֱלֹהֵינוּ. וְשָׁם נַעֲשֶׂה לְפָנֶיךָ אֶת קָרְבְּנוֹת חוֹבוֹתֵינוּ, תְּמִידִים כְּסִדְרָם וּמוּסָפִים כְּהִלְכָתָם, אֶת מוּסַף יוֹם","cond":["musaf","pesach"]},{"kind":"text","text":"חַג הַמַּצּוֹת הַזֶּה","cond":["musaf","pesach","pesach"]},{"kind":"text","text":"חַג הַסֻּכּוֹת הַזֶּה","cond":["musaf","pesach","sucot"]},{"kind":"text","text":"יוֹם מִקְרָא קֹדֶשׁ הַזֶּה, נַעֲשֶׂה וְנַקְרִיב לְפָנֶיךָ בְּאַהֲבָה כְּמִצְוַת רְצוֹנָךְ, כְּמוֹ שֶׁכָּתַבְתָּ עָלֵינוּ בְּתוֹרָתָךְ, עַל יְדֵי מֹשֶׁה עַבְדֶּךָ.\n\nאֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן רַחֵם עָלֵינוּ, טוֹב וּמֵטִיב הִדָּרֶשׁ לָנוּ, שׁוּבָה עָלֵינוּ בַּהֲמוֹן רַחֲמֶיךָ בִּגְלַל אָבוֹת שֶׁעָשׂוּ רְצוֹנֶךָ, בְּנֵה בֵיתְךָ כְּבַתְּחִלָּה, כּונֵן בֵּית מִקְדָּשְׁךָ עַל מְכוֹנוֹ, הַרְאֵנוּ בְּבִנְיָנוֹ, שַׂמְּחֵנוּ בְּתִקּוּנוֹ, וְהָשֵׁב שְׁכִינָתְךָ לְתוֹכוֹ, וְהָשֵׁב כֹּהֲנִים לַעֲבוֹדָתָם וּלְוִיִּם לְשִׁירָם וּלְזִמְרָם, וְהָשֵׁב יִשְׂרָאֵל לִנְוֵיהֶם. וְשָׁם נַעֲלֶה וְנֵרָאֶה וְנִשְׁתַּחֲוֶה לְפָנֶיךָ בְּשָׁלֹשׁ פַּעֲמֵי רְגָלֵינוּ בְּכָל שָׁנָה וְשָׁנָה, כַּכָּתוּב בַּתּורָה: שָׁלֹשׁ פְּעָמִים בַּשָּׁנָה יֵרָאֶה כָל זְכוּרְךָ אֶת פְּנֵי יהוה אֱלֹהֶיךָ בַּמָּקום אֲשֶׁר יִבְחָר, בְּחַג הַמַּצּוֹת, וּבְחַג הַשָּׁבֻעוֹת, וּבְחַג הַסֻּכּוֹת, וְלא יֵרָאֶה אֶת פְּנֵי יהוה רֵיקָם: אִישׁ כְּמַתְּנַת יָדוֹ, כְּבִרְכַּת יהוה אֱלֹהֶיךָ אֲשֶׁר נָתַן לָךְ:\n\nוְהַשִּׂיאֵנוּ יהוה אֱלֹהֵינוּ אֶת בִּרְכַּת מוֹעֲדֶיךָ לְחַיִּים בְּשִׂמְחָה וּבְשָׁלוֹם, כַּאֲשֶׁר רָצִיתָ וְאָמַרְתָּ לְבָרְכֵנוּ, כֵּן תְּבָרְכֵנוּ סֶלָה. קַדְּשֵׁנוּ בְּמִצְוׂתֶיךָ, שִׂים חֶלְקֵנוּ בְּתוֹרָתָךְ, שַׂבְּעֵנוּ מִטּוּבָךְ, שַׂמֵּחַ נַפְשֵׁנוּ בִּישׁוּעָתָךְ, וְטַהֵר לִבֵּנוּ לְעָבְדְּךָ בֶאֱמֶת. וְהַנְחִילֵנוּ יהוה אֱלֹהֵינוּ בְּשִׂמְחָה וּבְשָׂשׂוֹן מוֹעֲדֵי קָדְשֶׁךָ, וְיִשְׂמְחוּ בְךָ כָּל יִשְׂרָאֵל מְקַדְּשֵׁי שְׁמֶךָ. בָּרוּךְ אַתָּה יהוה, מְקַדֵּשׁ יִשְׂרָאֵל וְהַזְּמַנִּים.","cond":["musaf","pesach"]},{"kind":"text","text":"רְצֵה יְהֹוָה אֱלֹהֵינוּ בְּעַמְּךָ יִשְׂרָאֵל, וּלִתְפִלָּתָם שְׁעֵה, וְהָשֵׁב הָעֲבוֹדָה לִדְבִיר בֵּיתֶךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם מְהֵרָה בְאַהֲבָה תְּקַבֵּל בְּרָצוֹן, וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּךָ. וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים תַּחְפֹּץ בָּנוּ וְתִרְצֵנוּ, וְתֶחֱזֶינָה עֵינֵינוּ בְּשׁוּבְךָ לְצִיּוֹן בְּרַחֲמִים. בָּרוּךְ אַתָּה יִהִוִהִ, הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן.","cond":["musaf"]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שֶׁאַתָּה הוּא יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ לְעוֹלָם וָעֶד, צוּרֵנוּ צוּר חַיֵּינוּ וּמָגֵן יִשְׁעֵנוּ אַתָּה הוּא לְדֹר וָדֹר. נוֹדֶה לְּךָ וּנְסַפֵּר תְּהִלָּתֶךָ, עַל חַיֵּינוּ הַמְּסוּרִים בְּיָדֶךָ, וְעַל נִשְׁמוֹתֵינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּיךָ שֶׁבְּכָל יוֹם עִמָּנוּ, וְעַל נִפְלְאוֹתֶיךָ וְטוֹבוֹתֶיךָ שֶׁבְּכָל עֵת, עֶרֶב וָבֹקֶר וְצָהֳרָיִם. הַטּוֹב, כִּי לֹא כָלוּ רַחֲמֶיךָ, הַמְרַחֵם, כִּי לֹא תַמּוּ חֲסָדֶיךָ, כִּי מֵעוֹלָם קִוִּינוּ לָךְ.","cond":["musaf"]},{"kind":"header","text":"מודים דרבנן","cond":["musaf"]},{"kind":"instruction","text":"מודים דרבנן:","cond":["musaf"]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שֶׁאַתָּה הוּא יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי כָל בָּשָׁר, יוֹצְרֵנוּ יוֹצֵר בְּרֵאשִׁית. בְּרָכוֹת וְהוֹדָאוֹת לְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ, עַל שֶׁהֶחֱיִיתָנוּ וְקִיַּמְתָּנוּ. כֵּן תְּחַיֵּנוּ וּתְחָנֵּנוּ וְתֶאֱסוֹף גָּלֻיּוֹתֵינוּ לְחַצְרוֹת קָדְשֶׁךָ, לִשְׁמֹר חֻקֶּיךָ וְלַעֲשׂוֹת רְצוֹנְךָ וּלְעָבְדְךָ בְלֵבָב שָׁלֵם, עַל שֶׁאֲנַחְנוּ מוֹדִים לָךְ, בָּרוּךְ אֵל הַהוֹדָאוֹת.","cond":["musaf"]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת, שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה, בִּימֵי מַתִּתְיָה בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְשַׁכְּחָם תּוֹרָתָךְ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנָךְ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וּטְמֵאִים בְּיַד טְהוֹרִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, לְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמָךְ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כָּךְ בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ בְּהַלֵּל גָּמוּר וּבְהוֹדָאָה, וְעָשִׂיתָ עִמָּהֶם נִסִּים וְנִפְלָאוֹת, וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל, סֶלָה.","cond":["musaf","chanuka"]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת, שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה, בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים, בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ, וְעָשִׂיתָ עִמָּהֶם נִסִּים וְנִפְלָאוֹת, וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל, סֶלָה.","cond":["musaf","purim"]},{"kind":"text","text":"וְעַל כֻּלָּם יִתְבָּרַךְ וְיִתְרוֹמַם וְיִתְנַשֵּׂא תָמִיד, שִׁמְךָ מַלְכֵּנוּ, לְעוֹלָם וָעֶד. וְכָל הַחַיִּים יוֹדוּךָ סֶּלָה.","cond":["musaf"]},{"kind":"special","text":"וּכְתֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶךָ.","cond":["musaf","ayt"]},{"kind":"text","text":"וִיהַלְלוּ וִיבָרְכוּ אֶת שִׁמְךָ הַגָּדוֹל, בֶּאֱמֶת, לְעוֹלָם כִּי טוֹב, הָאֵל יְשׁוּעָתֵנוּ וְעֶזְרָתֵנוּ סֶלָה, הָאֵל הַטּוֹב. בָּרוּךְ אַתָּה יֻהֻוֻהֻ, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת.","cond":["musaf"]},{"kind":"header","text":"ברכת כהנים","cond":["musaf"]},{"kind":"instruction","text":"ברכת כהנים לחזרת הש\"ץ:\n\nאם לא עלו כהנים לדוכן הש\"ץ אומר או\"א (נמצא בהמשך).\n\nאם עלו שני כהנים לדוכן קוראים להם - כֹּהֲנִים:\n\nהכהנים מברכים:","cond":["musaf"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בִּקְדֻשָּׁתוֹ שֶׁל אַהֲרֹן, וְצִוָּנוּ לְבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בְּאַהֲבָה.\n\nיְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ:\nיָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ:\nיִשָּׂא יהוה פָּנָיו אֵלֶיךָ וְיָשֵׂם לְךָ שָׁלוֹם:","cond":["musaf"]},{"kind":"instruction","text":"הקהל אומר:","cond":["musaf"]},{"kind":"text","text":"אַדִּיר בַּמָּרוֹם שׁוֹכֵן בִּגְבוּרָה, אַתָּה שָׁלוֹם וְשִׁמְךָ שָׁלוֹם. יְהִי רָצוֹן שֶׁתָּשִׂים עָלֵינוּ וְעַל כָּל עַמְּךָ בֵּית יִשְׂרָאֵל חַיִּים וּבְרָכָה לְמִשְׁמֶרֶת שָׁלוֹם.","cond":["musaf"]},{"kind":"instruction","text":"הכהנים אומרים","cond":["musaf"]},{"kind":"text","text":"רִבּוֹנוֹ שֶׁל עוֹלָם, עָשִׂינוּ מַה שֶּׁגָּזַרְתָּ עָלֵינוּ, אַף אַתָּה עֲשֵׂה עִמָּנוּ כְּמוֹ שֶׁהִבְטַחְתָּנוּ: הַשְׁקִיפָה מִמְּעוֹן קָדְשְׁךָ מִן הַשָּׁמַיִם, וּבָרֵךְ אֶת עַמְּךָ אֶת יִשְׂרָאֵל, וְאֵת הָאֲדָמָה אֲשֶׁר נָתַתָּה לָנוּ, כַּאֲשֶׁר נִשְׁבַּעְתָּ לַאֲבֹתֵינוּ, אֶרֶץ זָבַת חָלָב וּדְבָשׁ:","cond":["musaf"]},{"kind":"instruction","text":"אם לא עלו כהנים לדוכן הש\"ץ אומר:","cond":["musaf"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, בָּרְכֵנוּ בַּבְּרָכָה הַמְשֻׁלֶּשֶׁת בַּתּוֹרָה הַכְּתוּבָה עַל יְדֵי מֹשֶׁה עַבְדֶּךָ, הָאֲמוּרָה מִפִּי אַהֲרֹן וּבָנָיו כֹּהֲנִים עַם קְדוֹשֶׁךָ, כָּאָמוּר: יְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ: יָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ: יִשָּׂא יהוה פָּנָיו אֵלֶיךָ וְיָשֵׂם לְךָ שָׁלוֹם:","cond":["musaf"]},{"kind":"text","text":"שִׂים שָׁלוֹם טוֹבָה וּבְרָכָה, חַיִּים, חֵן וָחֶסֶד, צְדָקָה וְרַחֲמִים, עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל עַמֶּךָ. וּבָרְכֵנוּ אָבִינוּ, כֻּלָּנוּ כְאֶחָד בְּאוֹר פָּנֶיךָ, כִּי בְאוֹר פָּנֶיךָ נָתַתָּ לָּנוּ יְהֹוָה אֱלֹהֵינוּ, תּוֹרָה וְחַיִּים, אַהֲבָה וָחֶסֶד, צְדָקָה וְרַחֲמִים, בְּרָכָה וְשָׁלוֹם. וְטוֹב בְּעֵינֶיךָ לְבָרְכֵנוּ וּלְבָרֵךְ אֶת כָּל עַמְּךָ יִשְׂרָאֵל בְּרֹב עֹז וְשָׁלוֹם.","cond":["musaf"]},{"kind":"special","text":"וּבְסֵפֶר חֵיִּים, בְּרָכָה וְשָׁלוֹם, וּפַרְנָסָה טוֹבָה וִישׁוּעָה וְנֶחָמָה, וּגְזֵרוֹת טוֹבוֹת, נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ, אֲנַחְנוּ וְכָל עַמְּךָ יִשְׂרָאֵל, לְחַיִּים טוֹבִים וּלְשָׁלוֹם.","cond":["musaf","ayt"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יוּהוּווּהוּ, הַמְּבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם. אָמֵן.","cond":["musaf"]},{"kind":"text","text":"יִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:\n\nיְהִי שֵׁם יהוה מְבֹרָךְ מֵעַתָּה וְעַד עוֹלָם: מִמִּזְרַח שֶׁמֶשׁ עַד מְבוֹאוֹ, מְהֻלָּל שֵׁם יהוה: רָם עַל כָּל גּוֹיִם יהוה, עַל הַשָּׁמַיִם כְּבוֹדוֹ: יהוה אֲדֹנֵינוּ, מָה אַדִּיר שִׁמְךָ בְּכָל הָאָרֶץ:","cond":["musaf"]},{"kind":"header","text":"הושענות","cond":["musaf","sucot"]},{"kind":"instruction","text":"הושענות","cond":["musaf","sucot"]},{"kind":"text","text":"אֶרְחַץ בְּנִקָּיוֹן כַּפָּי וַאֲסֹבְבָה אֶת-מִזְבַּחֲךָ יהוה: לַשְׁמִעַ בְּקוֹל תּוֹדָה וּלְסַפֵּר כָּל-נִפְלְאוֹתֶיךָ:\n\nהוֹשַׁעְנָא, הוֹשַׁעְנָא.\n\nלְמַעַנְךָ אֱלֹהֵינוּ.\nלְמַעַנְךָ בּוֹרְאֵנוּ.\nלְמַעַנְךָ גּוֹאֲלֵנוּ.\nלְמַעַנְךָ דּוֹרְשֵׁנוּ.\n\nלְמַעַנְךָ אַדִּיר אַדִּירִים.\nלְמַעַנְךָ בּוֹרֵא רוּחַ וְיוֹצֵר הָרִים.\nלְמַעַנְךָ גְּדוֹל הָעֵצָה מַשְׁפִּיל וּמֵרִים.\nלְמַעַנְךָ דּוֹבֵר צֶדֶק מַגִּיד מֵישָׁרִים.\nלְמַעַנְךָ הַיּוֹדֵעַ וָעֵד אִם יִסָּתֵר אִישׁ בַּמִּסְתָּרִים.\nלְמַעַנְךָ וְהוּא בְאֶחָד וּמִי יְשִׁיבֶנּוּ אֲמָרִים.\nלְמַעַנְךָ זַךְ וְנָקִי וּמִתְבָּרֵר עִם בָּרִים.\nלְמַעַנְךָ חֹפֵשׂ מַצְפּוּן וְחוֹקֵר כָּל חֲדָרִים.\nלְמַעַנְךָ טִפְּחָה יְמִינוֹ שָׁמַיִם וְעָשָׂה מְאוֹרִים.\nלְמַעַנְךָ יָסַד אָרֶץ בַּצּוּרוֹת בִּקַּע יְאוֹרִים.\nלְמַעַנְךָ כַּבִּיר כֹּחַ מְכֻבָּד בָּאוּרִים.\nלְמַעַנְךָ לֹא יִתַּמּוּ שְׁנוֹתָיו לְדוֹר דּוֹרִים.\n\nהוֹשַׁעְנָא, הוֹשַׁעְנָא.\n\n==(==(\n\nאֲנִי וָהוּ הוֹשִׁיעָה נָּא. אֲנִי וָהוּ הוֹשִׁיעָה נָּא.\n\nכַּכָּתוּב: הוֹשִׁיעָה אֶת-עַמֶּךָ וּבָרֵךְ אֶת-נַחֲלָתֶךָ, וּרְעֵם וְנַשְּׂאֵם עַד-הָעוֹלָם: וְנֶאֱמַר: וְיִהְיוּ דְבָרַי אֵלֶּה אֲשֶׁר הִתְחַנַּנְתִּי לִפְנֵי יהוה קְרֹבִים אֶל-יהוה אֱלֹהֵינוּ יוֹמָם וָלָיְלָה, לַעֲשׂוֹת מִשְׁפַּט עַבְדּוֹ וּמִשְׁפַּט עַמּוֹ יִשְׂרָאֵל דְּבַר-יוֹם בְּיוֹמוֹ: לְמַעַן דַּעַת כָּל-עַמֵּי הָאָרֶץ כִּי יהוה הוּא הָאֱלֹהִים, אֵין עוֹד: לֹא-יָמוּשׁ סֵפֶר הַתּוֹרָה הַזֶּה מִפִּיךָ וְהָגִיתָ בּוֹ יוֹמָם וָלַיְלָה לְמַעַן תִּשְׁמֹר לַעֲשׂוֹת כְּכָל-הַכָּתוּב בּוֹ, כִּי-אָז תַּצְלִיחַ אֶת-דְּרָכֶךָ וְאָז תַּשְׂכִּיל: הֲלוֹא צִוִּיתִיךָ חֲזַק וֶאֱמָץ אַל-תַּעֲרֹץ וְאַל-תֵּחָת, כִּי עִמְּךָ יהוָה אֱלֹהֶיךָ בְּכֹל אֲשֶׁר תֵּלֵךְ:","cond":["musaf","sucot"]},{"kind":"instruction","text":"קדיש תתקבל","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.\nתִּתְקַבַּל צְלוֹתָנָא וּבָעוּתָנָא עִם צְלוֹתְהוֹן וּבָעוּתְהוֹן דְּכָל בֵּית יִשְׂרָאֵל קֳדָם אֲבוּנָא דְבִשְׁמַיָּא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא, חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה וְשֵיזָבָא וּרְפוּאָה וּגְאֻלָּה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה, לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"special","text":"בָּרְכִי נַפְשִׁי אֶת יהוה, יהוה אֱלֹהַי גָּדַלְתָּ מְּאֹד, הוֹד וְהָדָר לָבָשְׁתָּ:\nעֹטֶה אוֹר כַּשַּׂלְמָה נוֹטֶה שָׁמַיִם כַּיְרִיעָה:\nהַמְקָרֶה בַמַּיִם עֲלִיּוֹתָיו, הַשָּׂם עָבִים רְכוּבוֹ, הַמְהַלֵּךְ עַל כַּנְפֵי רוּחַ:\nעֹשֶׂה מַלְאָכָיו רוּחוֹת, מְשָׁרְתָיו אֵשׁ לֹהֵט:\nיָסַד אֶרֶץ עַל מְכוֹנֶיהָ, בַּל תִּמּוֹט עוֹלָם וָעֶד:\nתְּהוֹם כַּלְּבוּשׁ כִּסִּיתוֹ, עַל הָרִים יַעַמְדוּ מָיִם:\nמִן גַּעֲרָתְךָ יְנוּסוּן, מִן קוֹל רַעַמְךָ יֵחָפֵזוּן:\nיַעֲלוּ הָרִים, יֵרְדוּ בְקָעוֹת, אֶל מְקוֹם זֶה יָסַדְתָּ לָהֶם:\nגְּבוּל שַׂמְתָּ בַּל יַעֲבֹרוּן, בַּל יְשׁוּבוּן לְכַסּוֹת הָאָרֶץ:\nהַמְשַׁלֵּחַ מַעְיָנִים בַּנְּחָלִים בֵּין הָרִים יְהַלֵּכוּן:","cond":["musaf","rh"]},{"kind":"special","text":"יַשְׁקוּ כָּל חַיְתוֹ שָׂדָי, יִשְׁבְּרוּ פְרָאִים צְמָאָם:\nעֲלֵיהֶם עוֹף הַשָּׁמַיִם יִשְׁכּוֹן, מִבֵּין עֳפָאיִם יִתְּנוּ קוֹל:\nמַשְׁקֶה הָרִים מֵעֲלִיּוֹתָיו, מִפְּרִי מַעֲשֶׂיךָ תִּשְׂבַּע הָאָרֶץ:\nמַצְמִיחַ חָצִיר לַבְּהֵמָה וְעֵשֶׂב לַעֲבֹדַת הָאָדָם, לְהוֹצִיא לֶחֶם מִן הָאָרֶץ:\nוְיַיִן יְשַׂמַּח לְבַב אֱנוֹשׁ, לְהַצְהִיל פָּנִים מִשָּׁמֶן, וְלֶחֶם לְבַב אֱנוֹשׁ יִסְעָד:\nיִשְׂבְּעוּ עֲצֵי יהוה, אַרְזֵי לְבָנוֹן אֲשֶׁר נָטָע:\nאֲשֶׁר שָׁם צִפֳּרִים יְקַנֵּנוּ, חֲסִידָה בְּרוֹשִׁים בֵּיתָהּ:\nהָרִים הַגְּבֹהִים לַיְּעֵלִים, סְלָעִים מַחְסֶה לַשְׁפַנִּים:\nעָשָׂה יָרֵחַ לְמוֹעֲדִים, שֶׁמֶשׁ יָדַע מְבוֹאוֹ:\nתָּשֶׁת חֹשֶׁךְ וִיהִי לָיְלָה, בּוֹ תִרְמֹשׂ כָּל חַיְתוֹ יָעַר:\nהַכְּפִירִים שֹׁאֲגִים לַטָּרֶף וּלְבַקֵּשׁ מֵאֵל אָכְלָם:\nתִּזְרַח הַשֶּׁמֶשׁ יֵאָסֵפוּן וְאֶל מְעוֹנֹתָם יִרְבָּצוּן:","cond":["musaf","rh"]},{"kind":"special","text":"יֵצֵא אָדָם לְפָעֳלוֹ וְלַעֲבֹדָתוֹ עֲדֵי עָרֶב:\nמָה רַבּוּ מַעֲשֶׂיךָ יהוה, כֻּלָּם בְּחָכְמָה עָשִׂיתָ, מָלְאָה הָאָרֶץ קִנְיָנֶךָ:\nזֶה הַיָּם גָּדוֹל וּרְחַב יָדָיִם, שָׁם רֶמֶשׂ וְאֵין מִסְפָּר, חַיּוֹת קְטַנּוֹת עִם גְּדֹלוֹת:\nשָׁם אֳנִיּוֹת יְהַלֵּכוּן, לִוְיָתָן זֶה יָצַרְתָּ לְשַׂחֶק בּוֹ:\nכֻּלָּם אֵלֶיךָ יְשַׂבֵּרוּן לָתֵת אָכְלָם בְּעִתּוֹ:\nתִּתֵּן לָהֶם יִלְקֹטוּן, תִּפְתַּח יָדְךָ יִשְׂבְּעוּן טוֹב:\nתַּסְתִּיר פָּנֶיךָ יִבָּהֵלוּן, תֹּסֵף רוּחָם יִגְוָעוּן וְאֶל עֲפָרָם יְשׁוּבוּן:\nתְּשַׁלַּח רוּחֲךָ יִבָּרֵאוּן וּתְחַדֵּשׁ פְּנֵי אֲדָמָה:\nיְהִי כְבוֹד יהוה לְעוֹלָם, יִשְׂמַח יהוה בְּמַעֲשָׂיו:\nהַמַּבִּיט לָאָרֶץ וַתִּרְעָד, יִגַּע בֶּהָרִים וְיֶעֱשָׁנוּ:\nאָשִׁירָה לַיהוה בְּחַיָּי, אֲזַמְּרָה לֵאלֹהַי בְּעוֹדִי:\nיֶעֱרַב עָלָיו שִׂיחִי, אָנֹכִי אֶשְׂמַח בַּיהוה:\nיִתַּמּוּ חַטָּאִים מִן הָאָרֶץ וּרְשָׁעִים עוֹד אֵינָם, בָּרְכִי נַפְשִׁי אֶת יהוה, הַלְלוּיָהּ:","cond":["musaf","rh"]},{"kind":"header","text":"מזמור לפסח","cond":["musaf","pesach"]},{"kind":"instruction","text":"מזמור לפסח","cond":["musaf","pesach"]},{"kind":"text","text":"הֹדוּ לַיהוה כִּי-טוֹב, כִּי לְעוֹלָם חַסְדּוֹ: יֹאמְרוּ גְּאוּלֵי יהוה אֲשֶׁר גְּאָלָם מִיַּד-צָר: וּמֵאֲרָצוֹת קִבְּצָם, מִמִּזְרָח וּמִמַּעֲרָב מִצָּפוֹן וּמִיָּם: תָּעוּ בַמִּדְבָּר בִּישִׁימוֹן דָּרֶךְ, עִיר מוֹשָׁב לֹא מָצָאוּ: רְעֵבִים גַּם-צְמֵאִים, נַפְשָׁם בָּהֶם תִּתְעַטָּף: וַיִּצְעֲקוּ אֶל-יהוה בַּצַּר לָהֶם, מִמְּצוּקוֹתֵיהֶם יַצִּילֵם: וַיַּדְרִיכֵם בְּדֶרֶךְ יְשָׁרָה, לָלֶכֶת אֶל-עִיר מוֹשָׁב: יוֹדוּ לַיהוה חַסְדּוֹ, וְנִפְלְאוֹתָיו לִבְנֵי אָדָם: כִּי-הִשְׂבִּיעַ נֶפֶשׁ שׁוֹקֵקָה, וְנֶפֶשׁ רְעֵבָה מִלֵּא-טוֹב: יֹשְׁבֵי חֹשֶׁךְ וְצַלְמָוֶת, אֲסִירֵי עֳנִי וּבַרְזֶל: כִּי-הִמְרוּ אִמְרֵי-אֵל, וַעֲצַת עֶלְיוֹן נָאָצוּ: וַיַּכְנַע בֶּעָמָל לִבָּם, כָּשְׁלוּ וְאֵין עֹזֵר: וַיִּזְעֲקוּ אֶל-יהוה בַּצַּר לָהֶם, מִמְּצֻקוֹתֵיהֶם יוֹשִׁיעֵם: יוֹצִיאֵם מֵחֹשֶׁךְ וְצַלְמָוֶת, וּמוֹסְרוֹתֵיהֶם יְנַתֵּק: יוֹדוּ לַיהוה חַסְדּוֹ, וְנִפְלְאוֹתָיו לִבְנֵי אָדָם: כִּי-שִׁבַּר דַּלְתוֹת נְחֹשֶׁת, וּבְרִיחֵי בַרְזֶל גִּדֵּעַ: אֱוִלִים מִדֶּרֶךְ פִּשְׁעָם, וּמֵעֲוׂנֹתֵיהֶם יִתְעַנּוּ: כָּל-אֹכֶל תְּתַעֵב נַפְשָׁם, וַיַּגִּיעוּ עַד-שַׁעֲרֵי מָוֶת: וַיִּזְעֲקוּ אֶל-יהוה בַּצַּר לָהֶם, מִמְּצֻקוֹתֵיהֶם יוֹשִׁיעֵם: יִשְׁלַח דְּבָרוֹ וְיִרְפָּאֵם, וִימַלֵּט מִשְּׁחִיתוֹתָם: יוֹדוּ לַיהוה חַסְדּוֹ, וְנִפְלְאוֹתָיו לִבְנֵי אָדָם: וְיִזְבְּחוּ זִבְחֵי תוֹדָה, וִיסַפְּרוּ מַעֲשָׂיו בְּרִנָּה: יוֹרְדֵי הַיָּם בָּאֳנִיּוֹת, עֹשֵׂי מְלָאכָה בְּמַיִם רַבִּים: הֵמָּה רָאוּ מַעֲשֵׂי יהוה וְנִפְלְאוֹתָיו בִּמְצוּלָה: וַיּאמֶר, וַיַּעֲמֵד רוּחַ סְעָרָה, וַתְּרוֹמֵם גַּלָּיו: יַעֲלוּ שָׁמַיִם יֵרְדוּ תְהוֹמוֹת, נַפְשָׁם בְּרָעָה תִתְמוֹגָג: יָחוֹגּוּ וְיָנוּעוּ כַּשִּׁכּוֹר, וְכָל-חָכְמָתָם תִּתְבַּלָּע: וַיִּצְעֲקוּ אֶל-יהוה בַּצַּר לָהֶם, וּמִמְּצוּקתֵיהֶם יוֹצִיאֵם: יָקֵם סְעָרָה לִדְמָמָה, וַיֶּחֱשׁוּ גַּלֵּיהֶם: וַיִּשְׂמְחוּ כִי-יִשְׁתֹּקוּ, וַיַּנְחֵם אֶל-מְחוֹז חֶפְצָם: יוֹדוּ לַיהוה חַסְדּוֹ, וְנִפְלְאוֹתָיו לִבְנֵי אָדָם: וִירוֹמְמוּהוּ בִּקְהַל-עָם, וּבְמוֹשַׁב זְקֵנִים יְהַלְלוּהוּ: יָשֵׂם נְהָרוֹת לְמִדְבָּר, וּמֹצָאֵי מַיִם לְצִמָּאוֹן: אֶרֶץ פְּרִי לִמְלֵחָה מֵרָעַת יוֹשְׁבֵי בָהּ: יָשֵׂם מִדְבָּר לַאֲגַם-מַיִם, וְאֶרֶץ צִיָּה לְמֹצָאֵי מָיִם: וַיּוֹשֶׁב שָׁם רְעֵבִים, וַיְכוֹנְנוּ עִיר מוֹשָׁב: וַיִּזְרְעוּ שָׂדוֹת וַיִּטְּעוּ כְרָמִים, וַיַּעֲשׂוּ פְּרִי תְבוּאָה: וַיְבָרְכֵם וַיִּרְבּוּ מְאֹד, וּבְהֶמְתָּם לֹא יַמְעִיט: וַיִּמְעֲטוּ וַיָּשֹׁחוּ מֵעֹצֶר רָעָה וְיָגוֹן: שֹׁפֵךְ בּוּז עַל-נְדִיבִים, וַיַּתְעֵם בְּתֹהוּ לֹא-דָרֶךְ: וַיְשַׂגֵּב אֶבְיוֹן מֵעוֹנִי, וַיָּשֶׂם כַּצֹּאן מִשְׁפָּחוֹת: יִרְאוּ יְשָׁרִים וְיִשְׂמָחוּ, וְכָל-עַוְלָה קָפְצָה פִּיהָ: מִי-חָכָם וְיִשְׁמָר-אֵלֶּה, וְיִתְבּוֹנְנוּ חַסְדֵּי יהוה:","cond":["musaf","pesach"]},{"kind":"header","text":"מזמורים לסוכות","cond":["musaf","sucot"]},{"kind":"instruction","text":"מזמורים לסוכות","cond":["musaf","sucot"]},{"kind":"text","text":"לַמְנַצֵּחַ מַשְׂכִּיל לִבְנֵי-קֹרַח: כְּאַיָּל תַּעֲרֹג עַל-אֲפִיקֵי-מָיִם, כֵּן נַפְשִׁי תַעֲרֹג אֵלֶיךָ אֱלֹהִים: צָמְאָה נַפְשִׁי לֵאלֹהִים, לְאֵל חָי, מָתַי אָבוֹא וְאֵרָאֶה פְּנֵי אֱלֹהִים: הָיְתָה-לִּי דִמְעָתִי לֶחֶם יוֹמָם וָלָיְלָה, בֶּאֱמֹר אֵלַי כָּל-הַיּוֹם אַיֵּה אֱלֹהֶיךָ: אֵלֶּה אֶזְכְּרָה וְאֶשְׁפְּכָה עָלַי נַפְשִׁי, כִּי אֶעֱבֹר בַּסָּךְ אֶדַּדֵּם עַד-בֵּית אֱלֹהִים, בְּקוֹל-רִנָּה וְתוֹדָה, הָמוֹן חוֹגֵג: מַה-תִּשְׁתּוֹחֲחִי נַפְשִׁי, וַתֶּהֱמִי עָלָי, הוֹחִילִי לֵאלֹהִים כִּי-עוֹד אוֹדֶנּוּ, יְשׁוּעוֹת פָּנָיו: אֱלֹהַי, עָלַי נַפְשִׁי תִשְׁתּוֹחָח, עַל-כֵּן אֶזְכָּרְךָ מֵאֶרֶץ יַרְדֵּן, וְחֶרְמוֹנִים מֵהַר מִצְעָר: תְּהוֹם-אֶל-תְּהוֹם קוֹרֵא לְקוֹל צִנּוֹרֶיךָ, כָּל-מִשְׁבָּרֶיךָ וְגַלֶּיךָ עָלַי עָבָרוּ: יוֹמָם יְצַוֶּה יהוה חַסְדּוֹ, וּבַלַּיְלָה שִׁירֹה עִמִּי, תְּפִלָּה לְאֵל חַיָּי: אוֹמְרָה לְאֵל סַלְעִי, לָמָה שְׁכַחְתָּנִי, לָמָּה-קֹדֵר אֵלֵךְ, בְּלַחַץ אוֹיֵב: בְּרֶצַח בְּעַצְמוֹתַי, חֵרְפוּנִי צוֹרְרָי, בְּאָמְרָם אֵלַי כָּל-הַיּוֹם אַיֵּה אֱלֹהֶיךָ: מַה-תִּשְׁתּוֹחֲחִי נַפְשִׁי, וּמַה-תֶּהֱמִי עָלָי, הוֹחִילִי לֵאלֹהִים כִּי-עוֹד אוֹדֶנּוּ, יְשׁוּעֹת פָּנַי וֵאלֹהָי:","cond":["musaf","sucot"]},{"kind":"text","text":"שָׁפְטֵנִי אֱלֹהִים וְרִיבָה רִיבִי, מִגּוֹי לֹא חָסִיד, מֵאִישׁ מִרְמָה וְעַוְלָה תְפַלְּטֵנִי: כִּי-אַתָּה אֱלֹהֵי מָעוּזִּי, לָמָה זְנַחְתָּנִי, לָמָּה-קֹדֵר אֶתְהַלֵּךְ בְּלַחַץ אוֹיֵב: שְׁלַח-אוֹרְךָ וַאֲמִתְּךָ הֵמָּה יַנְחוּנִי, יְבִיאוּנִי אֶל-הַר-קָדְשְׁךָ וְאֶל-מִשְׁכְּנוֹתֶיךָ: וְאָבוֹאָה אֶל-מִזְבַּח אֱלֹהִים, אֶל-אֵל שִׂמְחַת גִּילִי, וְאוֹדְךָ בְכִנּוֹר, אֱלֹהִים אֱלֹהָי: מַה-תִּשְׁתּוֹחֲחִי נַפְשִׁי, וּמַה-תֶּהֱמִי עָלָי, הוֹחִילִי לֵאלֹהִים כִּי-עוֹד אוֹדֶנּוּ, יְשׁוּעֹת פָּנַי וֵאלֹהָי:","cond":["musaf","sucot"]},{"kind":"instruction","text":"קדיש יהא שלמא","cond":["musaf"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא, חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה וְשֵיזָבָא וּרְפוּאָה וּגְאֻלָּה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה, לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["musaf"]},{"kind":"text","text":"עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["musaf"]},{"kind":"header","text":"שיר של יום","cond":["shirShelYomAtEnd"]},{"kind":"instruction","text":"שיר של יום","cond":["shirShelYomAtEnd"]},{"kind":"text","text":"תְּפִלָּה לְדָוִד, הַטֵּה יהוה אָזְנְךָ עֲנֵנִי, כִּי עָנִי וְאֶבְיוֹן אָנִי: שָׁמְרָה נַפְשִׁי כִּי חָסִיד אָנִי, הוֹשַׁע עַבְדְּךָ, אַתָּה אֱלֹהַי, הַבּוֹטֵחַ אֵלֶיךָ: חָנֵּנִי אֲדֹנָי, כִּי אֵלֶיךָ אֶקְרָא כָּל הַיּוֹם: שַׂמֵּחַ נֶפֶשׁ עַבְדֶּךָ, כִּי אֵלֶיךָ אֲדֹנָי נַפְשִׁי אֶשָּׂא: כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ: הַאֲזִינָה יהוה תְּפִלָּתִי וְהַקְשִׁיבָה בְּקוֹל תַּחֲנוּנוֹתָי: בְּיוֹם צָרָתִי אֶקְרָאֶךָּ כִּי תַעֲנֵנִי: אֵין כָּמוֹךָ בָאֱלֹהִים, אֲדֹנָי, וְאֵין כְּמַעֲשֶׂיךָ: כָּל גּוֹיִם אֲשֶׁר עָשִׂיתָ יָבוֹאוּ וְיִשְׁתַּחֲווּ לְפָנֶיךָ, אֲדֹנָי, וִיכַבְּדוּ לִשְׁמֶךָ: כִּי גָדוֹל אַתָּה וְעֹשֵׂה נִפְלָאוֹת, אַתָּה אֱלֹהִים לְבַדֶּךָ: הוֹרֵנִי יהוה דַּרְכֶּךָ, אֲהַלֵּךְ בַּאֲמִתֶּךָ, יַחֵד לְבָבִי לְיִרְאָה שְׁמֶךָ: אוֹדְךָ אֲדֹנָי אֱלֹהַי בְּכָל לְבָבִי, וַאֲכַבְּדָה שִׁמְךָ לְעוֹלָם: כִּי חַסְדְּךָ גָּדוֹל עָלָי, וְהִצַּלְתָּ נַפְשִׁי מִשְּׁאוֹל תַּחְתִּיָּה: אֱלֹהִים, זֵדִים קָמוּ עָלַי, וַעֲדַת עָרִיצִים בִּקְשׁוּ נַפְשִׁי, וְלֹא שָׂמוּךָ לְנֶגְדָּם: וְאַתָּה אֲדֹנָי אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב חֶסֶד וֶאֱמֶת: פְּנֵה אֵלַי וְחָנֵּנִי, תְּנָה עֻזְּךָ לְעַבְדֶּךָ, וְהוֹשִׁיעָה לְבֶן אֲמָתֶךָ: עֲשֵׂה עִמִּי אוֹת לְטוֹבָה, וְיִרְאוּ שֹׂנְאַי וְיֵבֹשׁוּ, כִּי אַתָּה יהוה עֲזַרְתַּנִי וְנִחַמְתָּנִי:","cond":["shirShelYomAtEnd","shacharitTachanun"]},{"kind":"text","text":"בֵּית יַעֲקֹב, לְכוּ וְנֵלְכָה בְּאוֹר יהוה: כִּי כָּל הָעַמִּים יֵלְכוּ אִישׁ בְּשֵׁם אֱלֹהָיו, וַאֲנַחְנוּ נֵלֵךְ בְּשֵׁם יהוה אֱלֹהֵינוּ לְעוֹלָם וָעֶד: יְהִי יהוה אֱלֹהֵינוּ עִמָּנוּ כַּאֲשֶׁר הָיָה עִם אבוֹתֵינוּ, אַל יַעַזְבֵנוּ וְאַל יִטְּשֵׁנוּ: לְהַטּות לְבָבֵנוּ אֵלָיו, לָלֶכֶת בְּכָל דְּרָכָיו וְלִשְׁמֹר מִצְוׂתָיו וְחֻקָּיו וּמִשְׁפָּטָיו אֲשֶׁר צִוָּה אֶת אֲבֹתֵינוּ: וְיִהְיוּ דְבָרַי אֵלֶּה אֲשֶׁר הִתְחַנַּנְתִּי לִפְנֵי יהוה קְרֹבִים אֶל יהוה אֱלֹהֵינוּ יוֹמָם וָלָיְלָה, לַעֲשׂוֹת מִשְׁפַּט עַבְדּוֹ וּמִשְׁפַּט עַמּוֹ יִשְׂרָאֵל דְּבַר יוֹם בְּיוֹמוֹ: לְמַעַן דַּעַת כָּל עַמֵּי הָאָרֶץ כִּי יהוה הוּא הָאֱלֹהִים, אֵין עוד:\n\nשִׁיר הַמַּעֲלוֹת לְדָוִד, לוּלֵי יהוה שֶׁהָיָה לָנוּ יֹאמַר נָא יִשְׂרָאֵל: לוּלֵי יהוה שֶׁהָיָה לָנוּ בְּקוּם עָלֵינוּ אָדָם: אֲזַי חַיִּים בְּלָעוּנוּ בַּחֲרוֹת אַפָּם בָּנוּ: אֲזַי הַמַּיִם שְׁטָפוּנוּ נַחְלָה עָבַר עַל נַפְשֵׁנוּ: אֲזַי עָבַר עַל נַפְשֵׁנוּ הַמַּיִם הַזֵּידוֹנִים: בָּרוּךְ יהוה שֶׁלֹּא נְתָנָנוּ טֶרֶף לְשִׁנֵּיהֶם: נַפְשֵׁנוּ כְּצִפּוֹר נִמְלְטָה מִפַּח יוֹקְשִׁים, הַפַּח נִשְׁבָּר וַאֲנַחְנוּ נִמְלָטְנוּ: עֶזְרֵנוּ בְּשֵׁם יהוה, עֹשֵׂה שָׁמַיִם וָאָרֶץ:","cond":["shirShelYomAtEnd"]},{"kind":"instruction","text":"כשמזכיר \"היום יום פלוני בשבת\" טוב לכון שהוא מקיים מצוות עשה מן התורה של זכירת השבת.","cond":["shirShelYomAtEnd"]},{"kind":"text","text":"הַיּוֹם יוֹם אֶחָד בַּשַּׁבָּת, הַשִּׁיר שֶׁהָיוּ הַלְוִיִּם אוֹמְרִים עַל הַדּוּכָן:","cond":["shirShelYomAtEnd","sun","shirOpenD"]},{"kind":"text","text":"הַיּוֹם יוֹם אֶחָד בַּשַּׁבָּת.","cond":["shirShelYomAtEnd","sun","ShirOpenND"]},{"kind":"text","text":"לְדָוִד מִזְמוֹר, לַיהוה הָאָרֶץ וּמְלוֹאָהּ, תֵּבֵל וְיֹשְׁבֵי בָהּ: כִּי הוּא עַל יַמִּים יְסָדָהּ, וְעַל נְהָרוֹת יְכוֹנְנֶהָ: מִי יַעֲלֶה בְהַר יהוה, וּמִי יָקוּם בִּמְקוֹם קָדְשׁוֹ: נְקִי כַפַּיִם וּבַר לֵבָב, אֲשֶׁר לֹא נָשָׂא לַשָּׁוְא נַפְשִׁי וְלֹא נִשְׁבַּע לְמִרְמָה: יִשָּׂא בְרָכָה מֵאֵת יהוה, וּצְדָקָה מֵאֱלֹהֵי יִשְׁעוֹ: זֶה דּוֹר דֹּרְשָׁיו, מְבַקְשֵׁי פָנֶיךָ יַעֲקֹב סֶלָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וְהִנָּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבוֹא מֶלֶךְ הַכָּבוֹד: מִי זֶה מֶלֶךְ הַכָּבוֹד, יהוה עִזּוּז וְגִבּוֹר, יהוה גִּבּוֹר מִלְחָמָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבֹא מֶלֶךְ הַכָּבוֹד: מִי הוּא זֶה מֶלֶךְ הַכָּבוֹד, יהוה צְבָאוֹת הוּא מֶלֶךְ הַכָּבוֹד סֶלָה:","cond":["shirShelYomAtEnd","sun"]},{"kind":"text","text":"הַיּוֹם יוֹם שֵׁנִי בַשַּׁבָּת, הַשִּׁיר שֶׁהָיוּ הַלְוִיִּם אוֹמְרִים עַל הַדּוּכָן:","cond":["shirShelYomAtEnd","mon","shirOpenD"]},{"kind":"text","text":"הַיּוֹם יוֹם שֵׁנִי בַשַּׁבָּת.","cond":["shirShelYomAtEnd","mon","ShirOpenND"]},{"kind":"text","text":"שִׁיר מִזְמוֹר לִבְנֵי קֹרַח: גָּדוֹל יהוה וּמְהֻלָּל מְאֹד בְּעִיר אֱלֹהֵינוּ הַר קָדְשׁוֹ: יְפֵה נוֹף, מְשׂוֹשׂ כָּל הָאָרֶץ, הַר צִיּוֹן יַרְכְּתֵי צָפוֹן קִרְיַת מֶלֶךְ רָב: אֱלֹהִים בְּאַרְמְנוֹתֶיהָ נוֹדַע לְמִשְׂגָּב: כִּי הִנֵּה הַמְּלָכִים נוֹעֲדוּ עָבְרוּ יַחְדָּו: הֵמָּה רָאוּ כֵּן תָּמָהוּ, נִבְהֲלוּ נֶחְפָּזוּ: רְעָדָה אֲחָזָתַם שָׁם, חִיל כַּיּוֹלֵדָה: בְּרוּחַ קָדִים תְּשַׁבֵּר אֳנִיּוֹת תַּרְשִׁישׁ: כַּאֲשֶׁר שָׁמַעְנוּ כֵּן רָאִינוּ בְּעִיר יהוה צְבָאוֹת בְּעִיר אֱלֹהֵינוּ, אֱלֹהִים יְכוֹנְנֶהָ עַד עוֹלָם סֶלָה: דִּמִּינוּ אֱלֹהִים חַסְדֶּךָ בְּקֶרֶב הֵיכָלֶךָ: כְּשִׁמְךָ אֱלֹהִים כֵּן תְּהִלָּתְךָ עַל קַצְוֵי אֶרֶץ, צֶדֶק מָלְאָה יְמִינֶךָ: יִשְׂמַח הַר צִיּוֹן, תָּגֵלְנָה בְּנוֹת יְהוּדָה, לְמַעַן מִשְׁפָּטֶיךָ: סֹבּוּ צִיּוֹן וְהַקִּיפוּהָ, סִפְרוּ מִגְדָּלֶיהָ: שִׁיתוּ לִבְּכֶם לְחֵילָה, פַּסְּגוּ אַרְמְנוֹתֶיהָ, לְמַעַן תְּסַפְּרוּ לְדוֹר אַחֲרוֹן: כִּי זֶה אֱלֹהִים אֱלֹהֵינוּ עוֹלָם וָעֶד, הוּא יְנַהֲגֵנוּ עַל מוּת:","cond":["shirShelYomAtEnd","mon"]},{"kind":"text","text":"הַיּוֹם יוֹם שְׁלִישִׁי בַשַּׁבָּת, הַשִּׁיר שֶׁהָיוּ הַלְוִיִּם אוֹמְרִים עַל הַדּוּכָן:","cond":["shirShelYomAtEnd","tue","shirOpenD"]},{"kind":"text","text":"הַיּוֹם יוֹם שְׁלִישִׁי בַשַּׁבָּת.","cond":["shirShelYomAtEnd","tue","ShirOpenND"]},{"kind":"text","text":"מִזְמוֹר לְאָסָף, אֱלֹהִים נִצָּב בַּעֲדַת אֵל, בְּקֶרֶב אֱלֹהִים יִשְׁפֹּט: עַד מָתַי תִּשְׁפְּטוּ עָוֶל וּפְנֵי רְשָׁעִים תִּשְׂאוּ סֶלָה: שִׁפְטוּ דַל וְיָתוֹם, עָנִי וָרָשׁ הַצְדִּיקוּ: פַּלְּטוּ דַל וְאֶבְיוֹן, מִיַּד רְשָׁעִים הַצִּילוּ: לֹא יָדְעוּ וְלֹא יָבִינוּ, בַּחֲשֵׁכָה יִתְהַלָּכוּ, יִמּוֹטוּ כָּל מוֹסְדֵי אָרֶץ: אֲנִי אָמַרְתִּי אֱלֹהִים אַתֶּם וּבְנֵי עֶלְיוֹן כֻּלְּכֶם: אָכֵן כְּאָדָם תְּמוּתוּן וּכְאַחַד הַשָּׂרִים תִּפֹּלוּ: קוּמָה אֱלֹהִים שָׁפְטָה הָאָרֶץ, כִּי אַתָּה תִנְחַל בְּכָל הַגּוֹיִם:","cond":["shirShelYomAtEnd","tue"]},{"kind":"text","text":"הַיּוֹם יוֹם רְבִיעִי בַשַּׁבָּת, הַשִּׁיר שֶׁהָיוּ הַלְוִיִּם אוֹמְרִים עַל הַדּוּכָן:","cond":["shirShelYomAtEnd","wed","shirOpenD"]},{"kind":"text","text":"הַיּוֹם יוֹם רְבִיעִי בַשַּׁבָּת.","cond":["shirShelYomAtEnd","wed","ShirOpenND"]},{"kind":"text","text":"אֵל נְקָמוֹת יהוה, אֵל נְקָמוֹת הוֹפִיעַ: הִנָּשֵׂא שֹׁפֵט הָאָרֶץ, הָשֵׁב גְּמוּל עַל גֵּאִים: עַד מָתַי רְשָׁעִים, יהוה, עַד מָתַי רְשָׁעִים יַעֲלֹזוּ: יַבִּיעוּ יְדַבְּרוּ עָתָק, יִתְאַמְּרוּ כָּל פֹעֲלֵי אָוֶן: עַמְּךָ יהוה יְדַכְּאוּ, וְנַחֲלָתְךָ יְעַנּוּ: אַלְמָנָה וְגֵר יַהֲרֹגוּ, וִיתוֹמִים יְרַצֵּחוּ: וַיֹּאמְרוּ לֹא יִרְאֶה יָהּ, וְלֹא יָבִין אֱלֹהֵי יַעֲקֹב: בִּינוּ בֹּעֲרִים בָּעָם, וּכְסִילִים מָתַי תַּשְׂכִּילוּ: הַנֹּטַע אֹזֶן הֲלֹא יִשְׁמָע, אִם יֹצֵר עַיִן הֲלֹא יַבִּיט: הֲיֹסֵר גּוֹיִם הֲלֹא יוֹכִיחַ, הַמְלַמֵּד אָדָם דָּעַת: יהוה יֹדֵעַ מַחְשְׁבוֹת אָדָם כִּי הֵמָּה הָבֶל: אַשְׁרֵי הַגֶּבֶר אֲשֶׁר תְּיַסְּרֶנּוּ יָּהּ, וּמִתּוֹרָתְךָ תְלַמְּדֶנּוּ: לְהַשְׁקִיט לוֹ מִימֵי רָע, עַד יִכָּרֶה לָרָשָׁע שָׁחַת: כִּי לֹא יִטֹּשׁ יהוה עַמּוֹ, וְנַחֲלָתוֹ לֹא יַעֲזֹב: כִּי עַד צֶדֶק יָשׁוּב מִשְׁפָּט, וְאַחֲרָיו כָּל יִשְׁרֵי לֵב: מִי יָקוּם לִי עִם מְרֵעִים, מִי יִתְיַצֵּב לִי עִם פֹּעֲלֵי אָוֶן: לוּלֵי יהוה עֶזְרָתָה לִּי, כִּמְעַט שָׁכְנָה דוּמָה נַפְשִׁי: אִם אָמַרְתִּי מָטָה רַגְלִי, חַסְדְּךָ יהוה יִסְעָדֵנִי: בְּרֹב שַׂרְעַפַּי בְּקִרְבִּי, תַּנְחוּמֶיךָ יְשַׁעַשְׁעוּ נַפְשִׁי: הַיְחָבְרְךָ כִּסֵּא הַוּוֹת, יֹצֵר עָמָל עֲלֵי חֹק: יָגוֹדּוּ עַל נֶפֶשׁ צַדִּיק, וְדָם נָקִי יַרְשִׁיעוּ: וַיְהִי יהוה לִי לְמִשְׂגָּב, וֵאלֹהַי לְצוּר מַחְסִי: וַיָּשֶׁב עֲלֵיהֶם אֶת אוֹנָם וּבְרָעָתָם יַצְמִיתֵם, יַצְמִיתֵם יהוה אֱלֹהֵינוּ:","cond":["shirShelYomAtEnd","wed"]},{"kind":"text","text":"הַיּוֹם יוֹם חֲמִישִׁי בַשַּׁבָּת, הַשִּׁיר שֶׁהָיוּ הַלְוִיִּם אוֹמְרִים עַל הַדּוּכָן:","cond":["shirShelYomAtEnd","thu","shirOpenD"]},{"kind":"text","text":"הַיּוֹם יוֹם חֲמִישִׁי בַשַּׁבָּת.","cond":["shirShelYomAtEnd","thu","ShirOpenND"]},{"kind":"text","text":"לַמְנַצֵּחַ עַל הַגִּתִּית לְאָסָף: הַרְנִינוּ לֵאלֹהִים עֻזֵּנוּ, הָרִיעוּ לֵאלֹהֵי יַעֲקֹב: שְׂאוּ זִמְרָה וּתְנוּ תֹף, כִּנּוֹר נָעִים עִם נָבֶל: תִּקְעוּ בַחֹדֶשׁ שׁוֹפָר, בַּכֵּסֶה לְיוֹם חַגֵּנוּ: כִּי חֹק לְיִשְׂרָאֵל הוּא, מִשְׁפָּט לֵאלֹהֵי יַעֲקֹב: עֵדוּת בִּיהוֹסֵף שָׂמוֹ בְּצֵאתוֹ עַל אֶרֶץ מִצְרָיִם, שְׂפַת לֹא יָדַעְתִּי אֶשְׁמָע: הֲסִירוֹתִי מִסֵּבֶל שִׁכְמוֹ, כַּפָּיו מִדּוּד תַּעֲבֹרְנָה: בַּצָּרָה קָרָאתָ וָאֲחַלְּצֶךָּ, אֶעֶנְךָ בְּסֵתֶר רַעַם, אֶבְחָנְךָ עַל מֵי מְרִיבָה סֶלָה: שְׁמַע עַמִּי וְאָעִידָה בָּךְ, יִשְׂרָאֵל אִם תִּשְׁמַע לִי: לֹא יִהְיֶה בְךָ אֵל זָר, וְלֹא תִשְׁתַּחֲוֶה לְאֵל נֵכָר: אָנֹכִי יהוה אֱלֹהֶיךָ הַמַּעַלְךָ מֵאֶרֶץ מִצְרָיִם, הַרְחֶב פִּיךָ וַאֲמַלְאֵהוּ: וְלֹא שָׁמַע עַמִּי לְקוֹלִי, וְיִשְׂרָאֵל לֹא אָבָה לִי: וָאֲשַׁלְּחֵהוּ בִּשְׁרִירוּת לִבָּם, יֵלְכוּ בְּמוֹעֲצוֹתֵיהֶם: לוּ עַמִּי שֹׁמֵעַ לִי, יִשְׂרָאֵל בִּדְרָכַי יְהַלֵּכוּ: כִּמְעַט אוֹיְבֵיהֶם אַכְנִיעַ, וְעַל צָרֵיהֶם אָשִׁיב יָדִי: מְשַׂנְאֵי יהוה יְכַחֲשׁוּ לוֹ, וִיהִי עִתָּם לְעוֹלָם: וַיַּאֲכִילֵהוּ מֵחֵלֶב חִטָּה, וּמִצּוּר, דְּבַשׁ אַשְׂבִּיעֶךָ:","cond":["shirShelYomAtEnd","thu"]},{"kind":"text","text":"הַיּוֹם יוֹם הַשִּׁשִּׁי בַשַּׁבָּת, הַשִּׁיר שֶׁהָיוּ הַלְוִיִּם אוֹמְרִים עַל הַדּוּכָן:","cond":["shirShelYomAtEnd","fri","shirOpenD"]},{"kind":"text","text":"הַיּוֹם יוֹם הַשִּׁשִּׁי בַשַּׁבָּת.","cond":["shirShelYomAtEnd","fri","ShirOpenND"]},{"kind":"text","text":"יהוה מָלָךְ גֵּאוּת לָבֵשׁ, לָבֵשׁ יהוה עֹז הִתְאַזָּר, אַף תִּכּוֹן תֵּבֵל בַּל תִּמּוֹט: נָכוֹן כִּסְאֲךָ מֵאָז, מֵעוֹלָם אָתָּה: נָשְׂאוּ נְהָרוֹת, יהוה, נָשְׂאוּ נְהָרוֹת קוֹלָם, יִשְׂאוּ נְהָרוֹת דָכְיָם: מִקֹּלוֹת מַיִם רַבִּים, אַדִּירִים מִשְׁבְּרֵי יָם, אַדִּיר בַּמָּרוֹם יהוה: עֵדֹתֶיךָ נֶאֶמְנוּ מְאֹד לְבֵיתְךָ נַאֲוָה קֹדֶשׁ, יהוה, לְאֹרֶךְ יָמִים:","cond":["shirShelYomAtEnd","fri"]},{"kind":"instruction","text":"בבית האבל אומרים מזמור זה:","cond":["shirShelYomAtEnd"]},{"kind":"text","text":"לַמְנַצֵּחַ לִבְנֵי קֹרַח מִזְמוֹר: שִׁמְעוּ זֹאת כָּל הָעַמִּים, הַאֲזִינוּ כָּל יֹשְׁבֵי חָלֶד: גַּם בְּנֵי אָדָם, גַּם בְּנֵי אִישׁ, יַחַד עָשִׁיר וְאֶבְיוֹן: פִּי יְדַבֵּר חָכְמוֹת, וְהָגוּת לִבִּי תְבוּנוֹת: אַטֶּה לְמָשָׁל אָזְנִי, אֶפְתַּח בְּכִנּוֹר חִידָתִי: לָמָּה אִירָא בִּימֵי רָע, עֲוׂן עֲקֵבַי יְסוּבֵּנִי: הַבֹּטְחִים עַל חֵילָם, וּבְרֹב עָשְׁרָם יִתְהַלָּלוּ: אָח לֹא פָדֹה יִפְדֶּה אִישׁ, לֹא יִתֵּן לֵאלֹהִים כָּפְרוֹ: וְיֵקַר פִּדְיוֹן נַפְשָׁם, וְחָדַל לְעוֹלָם: וִיחִי עוֹד לָנֶצַח, לֹא יִרְאֶה הַשָּׁחַת: כִּי יִרְאֶה חֲכָמִים יָמוּתוּ, יַחַד כְּסִיל וָבַעַר יֹאבֵדוּ, וְעָזְבוּ לַאֲחֵרִים חֵילָם: קִרְבָּם בָּתֵּימוֹ לְעוֹלָם, מִשְׁכְּנֹתָם לְדֹר וָדֹר, קָרְאוּ בִשְׁמוֹתָם עֲלֵי אֲדָמוֹת: וְאָדָם בִּיקָר בַּל יָלִין, נִמְשַׁל כַּבְּהֵמוֹת נִדְמוּ: זֶה דַרְכָּם כֵּסֶל לָמוֹ, וְאַחֲרֵיהֶם בְּפִיהֶם יִרְצוּ סֶלָה: כַּצֹּאן לִשְׁאוֹל שַׁתּוּ מָוֶת יִרְעֵם, וַיִּרְדּוּ בָם יְשָׁרִים לַבֹּקֶר, וְצוּרָם לְבַלּוֹת שְׁאוֹל מִזְּבֻל לוֹ: אַךְ אֱלֹהִים יִפְדֶּה נַפְשִׁי מִיַּד שְׁאוֹל, כִּי יִקָּחֵנִי סֶלָה: אַל תִּירָא כִּי יַעֲשִׁר אִישׁ, כִּי יִרְבֶּה כְּבוֹד בֵּיתוֹ: כִּי לֹא בְמוֹתוֹ יִקַּח הַכֹּל, לֹא יֵרֵד אַחֲרָיו כְּבוֹדוֹ: כִּי נַפְשׁוֹ בְּחַיָּיו יְבָרֵךְ, וְיוֹדֻךָ כִּי תֵיטִיב לָךְ: תָּבוֹא עַד דּוֹר אֲבוֹתָיו, עַד נֵצַח לֹא יִרְאוּ אוֹר: אָדָם בִּיקָר וְלֹא יָבִין נִמְשַׁל כַּבְּהֵמוֹת נִדְמוּ:","cond":["shirShelYomAtEnd"]},{"kind":"header","text":"הושיענו","cond":["shirShelYomAtEnd"]},{"kind":"instruction","text":"בכל יום אחרי שיר של יום אומרים:","cond":["shirShelYomAtEnd"]},{"kind":"text","text":"הוֹשִׁיעֵנוּ יהוה אֱלֹהֵינוּ וְקַבְּצֵנוּ מִן הַגּוֹיִם, לְהֹדוֹת לְשֵׁם קָדְשֶׁךָ לְהִשְׁתַּבֵּחַ בִּתְהִלָּתֶךָ: בָּרוּךְ יהוה אֱלֹהֵי יִשְׂרָאֵל מִן הָעוֹלָם וְעַד הָעוֹלָם, וְאָמַר כָּל הָעָם אָמֵן הַלְלוּיָהּ: בָּרוּךְ יהוה מִצִּיּוֹן, שֹׁכֵן יְרוּשָׁלִָם הַלְלוּיָהּ: בָּרוּךְ יהוה אֱלֹהִים אֱלֹהֵי יִשְׂרָאֵל, עֹשֵׂה נִפְלָאוֹת לְבַדּוֹ: וּבָרוּךְ שֵׁם כְּבוֹדוֹ לְעוֹלָם, וְיִמָּלֵא כְבוֹדוֹ אֶת כָּל הָאָרֶץ, אָמֵן וְאָמֵן:","cond":["shirShelYomAtEnd"]},{"kind":"special","text":"מזמור לשבעה עשר בתמוז:","cond":["shirShelYomAtEnd","17tammuz"]},{"kind":"text","text":"מִזְמוֹר לְאָסָף, אֱלֹהִים, בָּאוּ גוֹיִם בְּנַחֲלָתֶךָ טִמְּאוּ אֶת הֵיכַל קָדְשֶׁךָ, שָׂמוּ אֶת יְרוּשָׁלַיִם לְעִיִּים: נָתְנוּ אֶת נִבְלַת עֲבָדֶיךָ מַאֲכָל לְעוֹף הַשָּׁמָיִם, בְּשַׂר חֲסִידֶיךָ לְחַיְתוֹ אָרֶץ: שָׁפְכוּ דָמָם כַּמַּיִם סְבִיבוֹת יְרוּשָׁלִָם וְאֵין קוֹבֵר: הָיִינוּ חֶרְפָּה לִשְׁכֵנֵינוּ, לַעַג וָקֶלֶס לִסְבִיבוֹתֵינוּ: עַד מָה יהוה תֶּאֱנַף לָנֶצַח, תִּבְעַר כְּמוֹ אֵשׁ קִנְאָתֶךָ: שְׁפֹךְ חֲמָתְךָ אֶל הַגּוֹיִם אֲשֶׁר לֹא יְדָעוּךָ, וְעַל מַמְלָכוֹת אֲשֶׁר בְּשִׁמְךָ לֹא קָרָאוּ: כִּי אָכַל אֶת יַעֲקֹב וְאֶת נָוֵהוּ הֵשַׁמּוּ: אַל תִּזְכָּר לָנוּ עֲוׂנֹת רִאשֹׁנִים, מַהֵר יְקַדְּמוּנוּ רַחֲמֶיךָ כִּי דַלּוֹנוּ מְאֹד: עָזְרֵנוּ אֱלֹהֵי יִשְׁעֵנוּ עַל דְּבַר כְּבוֹד שְׁמֶךָ, וְהַצִּילֵנוּ וְכַפֵּר עַל חַטֹּאתֵינוּ לְמַעַן שְׁמֶךָ: לָמָּה יֹאמְרוּ הַגּוֹיִם אַיֵּה אֱלֹהֵיהֶם, יִוָּדַע בַּגּוֹיִם לְעֵינֵינוּ נִקְמַת דַּם עֲבָדֶיךָ הַשָּׁפוּךְ: תָּבוֹא לְפָנֶיךָ אֶנְקַת אָסִיר כְּגֹדֶל זְרוֹעֲךָ הוֹתֵר בְּנֵי תְמוּתָה: וְהָשֵׁב לִשְׁכֵנֵינוּ שִׁבְעָתַיִם אֶל חֵיקָם חֶרְפָּתָם אֲשֶׁר חֵרְפוּךָ אֲדֹנָי: וַאֲנַחְנוּ עַמְּךָ וְצֹאן מַרְעִיתֶךָ נוֹדֶה לְּךָ לְעוֹלָם, לְדֹר וָדֹר נְסַפֵּר תְּהִלָּתֶךָ:","cond":["shirShelYomAtEnd","17tammuz"]},{"kind":"special","text":"מזמור למחרת יום הכיפורים:","cond":["shirShelYomAtEnd","11tishrei"]},{"kind":"text","text":"לַמְנַצֵּחַ לִבְנֵי-קֹרַח מִזְמוֹר: רָצִיתָ יהוה אַרְצֶךָ, שַׁבְתָּ שְׁבִית יַעֲקֹב: נָשָׂאתָ עֲוׂן עַמֶּךָ, כִּסִּיתָ כָל-חַטָּאתָם סֶלָה: אָסַפְתָּ כָל-עֶבְרָתֶךָ, הֱשִׁיבוֹתָ מֵחֲרוֹן אַפֶּךָ: שׁוּבֵנוּ אֱלֹהֵי יִשְׁעֵנוּ, וְהָפֵר כַּעַסְךָ עִמָּנוּ: הַלְעוֹלָם תֶּאֱנַף-בָּנוּ, תִּמְשֹׁךְ אַפְּךָ לְדֹר וָדֹר: הֲלֹא-אַתָּה תָּשׁוּב תְּחַיֵּנוּ, וְעַמְּךָ יִשְׂמְחוּ-בָךְ: הַרְאֵנוּ יהוה חַסְדֶּךָ, וְיֶשְׁעֲךָ תִּתֶּן-לָנוּ: אֶשְׁמְעָה מַה-יְדַבֵּר הָאֵל יהוה, כִּי יְדַבֵּר שָׁלוֹם אֶל-עַמּוֹ וְאֶל-חֲסִידָיו, וְאַל-יָשׁוּבוּ לְכִסְלָה: אַךְ קָרוֹב לִירֵאָיו יִשְׁעוֹ, לִשְׁכֹּן כָּבוֹד בְּאַרְצֵנוּ: חֶסֶד-וֶאֱמֶת נִפְגָּשׁוּ, צֶדֶק וְשָׁלוֹם נָשָׁקוּ: אֱמֶת מֵאֶרֶץ תִּצְמָח, וְצֶדֶק מִשָּׁמַיִם נִשְׁקָף: גַּם-יהוה יִתֵּן הַטּוֹב, וְאַרְצֵנוּ תִּתֵּן יְבוּלָהּ: צֶדֶק לְפָנָיו יְהַלֵּךְ, וְיָשֵׂם לְדֶרֶךְ פְּעָמָיו:","cond":["shirShelYomAtEnd","11tishrei"]},{"kind":"special","text":"מזמור לצום גדליה ולעשרה בטבת:","cond":["shirShelYomAtEnd","gedalya"]},{"kind":"text","text":"שִׁיר מִזְמוֹר לְאָסָף: אֱלֹהִים אַל דֳּמִי לָךְ, אַל תֶּחֱרַשׁ וְאַל תִּשְׁקֹט אֵל: כִּי הִנֵּה אוֹיְבֶיךָ יֶהֱמָיוּן, וּמְשַׂנְאֶיךָ נָשְׂאוּ רֹאשׁ: עַל עַמְּךָ יַעֲרִימוּ סוֹד, וְיִתְיָעֲצוּ עַל צְפוּנֶיךָ: אָמְרוּ לְכוּ וְנַכְחִידֵם מִגּוֹי, וְלֹא יִזָּכֵר שֵׁם יִשְׂרָאֵל עוֹד: כִּי נוֹעֲצוּ לֵב יַחְדָּו, עָלֶיךָ בְּרִית יִכְרֹתוּ: אָהֳלֵי אֱדוֹם וְיִשְׁמְעֵאלִים, מוֹאָב וְהַגְרִים: גְּבָל וְעַמּוֹן וַעֲמָלֵק, פְּלֶשֶׁת עִם יֹשְׁבֵי צוֹר: גַּם אַשּׁוּר נִלְוָה עִמָּם, הָיוּ זְרוֹעַ לִבְנֵי לוֹט סֶלָה: עֲשֵׂה לָהֶם כְּמִדְיָן, כְּסִיסְרָא כְיָבִין בְּנַחַל קִישׁוֹן: נִשְׁמְדוּ בְעֵין דֹּאר, הָיוּ דֹּמֶן לָאֲדָמָה: שִׁיתֵמוֹ נְדִיבֵמוֹ כְּעֹרֵב וְכִזְאֵב, וּכְזֶבַח וּכְצַלְמֻנָּע כָּל נְסִיכֵמוֹ: אֲשֶׁר אָמְרוּ נִירְשָׁה לָּנוּ, אֵת נְאוֹת אֱלֹהִים: אֱלֹהַי, שִׁיתֵמוֹ כַגַּלְגַּל, כְּקַשׁ לִפְנֵי רוּחַ: כְּאֵשׁ תִּבְעַר יָעַר, וּכְלֶהָבָה תְּלַהֵט הָרִים: כֵּן תִּרְדְּפֵם בְּסַעֲרֶךָ, וּבְסוּפָתְךָ תְבַהֲלֵם: מַלֵּא פְנֵיהֶם קָלוֹן, וִיבַקְשׁוּ שִׁמְךָ יהוה: יֵבֹשׁוּ וְיִבָּהֲלוּ עֲדֵי עַד, וְיַחְפְּרוּ וְיֹאבֵדוּ: וְיֵדְעוּ כִּי אַתָּה שִׁמְךָ יהוה לְבַדֶּךָ, עֶלְיוֹן עַל כָּל הָאָרֶץ:","cond":["shirShelYomAtEnd","gedalya"]},{"kind":"special","text":"מזמור לצום גדליה ולעשרה בטבת:","cond":["shirShelYomAtEnd","10tevet"]},{"kind":"text","text":"שִׁיר מִזְמוֹר לְאָסָף: אֱלֹהִים אַל דֳּמִי לָךְ, אַל תֶּחֱרַשׁ וְאַל תִּשְׁקֹט אֵל: כִּי הִנֵּה אוֹיְבֶיךָ יֶהֱמָיוּן, וּמְשַׂנְאֶיךָ נָשְׂאוּ רֹאשׁ: עַל עַמְּךָ יַעֲרִימוּ סוֹד, וְיִתְיָעֲצוּ עַל צְפוּנֶיךָ: אָמְרוּ לְכוּ וְנַכְחִידֵם מִגּוֹי, וְלֹא יִזָּכֵר שֵׁם יִשְׂרָאֵל עוֹד: כִּי נוֹעֲצוּ לֵב יַחְדָּו, עָלֶיךָ בְּרִית יִכְרֹתוּ: אָהֳלֵי אֱדוֹם וְיִשְׁמְעֵאלִים, מוֹאָב וְהַגְרִים: גְּבָל וְעַמּוֹן וַעֲמָלֵק, פְּלֶשֶׁת עִם יֹשְׁבֵי צוֹר: גַּם אַשּׁוּר נִלְוָה עִמָּם, הָיוּ זְרוֹעַ לִבְנֵי לוֹט סֶלָה: עֲשֵׂה לָהֶם כְּמִדְיָן, כְּסִיסְרָא כְיָבִין בְּנַחַל קִישׁוֹן: נִשְׁמְדוּ בְעֵין דֹּאר, הָיוּ דֹּמֶן לָאֲדָמָה: שִׁיתֵמוֹ נְדִיבֵמוֹ כְּעֹרֵב וְכִזְאֵב, וּכְזֶבַח וּכְצַלְמֻנָּע כָּל נְסִיכֵמוֹ: אֲשֶׁר אָמְרוּ נִירְשָׁה לָּנוּ, אֵת נְאוֹת אֱלֹהִים: אֱלֹהַי, שִׁיתֵמוֹ כַגַּלְגַּל, כְּקַשׁ לִפְנֵי רוּחַ: כְּאֵשׁ תִּבְעַר יָעַר, וּכְלֶהָבָה תְּלַהֵט הָרִים: כֵּן תִּרְדְּפֵם בְּסַעֲרֶךָ, וּבְסוּפָתְךָ תְבַהֲלֵם: מַלֵּא פְנֵיהֶם קָלוֹן, וִיבַקְשׁוּ שִׁמְךָ יהוה: יֵבֹשׁוּ וְיִבָּהֲלוּ עֲדֵי עַד, וְיַחְפְּרוּ וְיֹאבֵדוּ: וְיֵדְעוּ כִּי אַתָּה שִׁמְךָ יהוה לְבַדֶּךָ, עֶלְיוֹן עַל כָּל הָאָרֶץ:","cond":["shirShelYomAtEnd","10tevet"]},{"kind":"special","text":"מזמור לתענית אסתר ולפורים:","cond":["shirShelYomAtEnd","purim"]},{"kind":"text","text":"לַמְנַצֵּחַ עַל אַיֶּלֶת הַשַּׁחַר, מִזְמוֹר לְדָוִד: אֵלִי אֵלִי לָמָה עֲזַבְתָּנִי, רָחוֹק מִישׁוּעָתִי דִּבְרֵי שַׁאֲגָתִי: אֱלֹהַי, אֶקְרָא יוֹמָם וְלֹא תַעֲנֶה, וְלַיְלָה וְלֹא דוּמִיָּה לִי: וְאַתָּה קָדוֹשׁ, יוֹשֵׁב תְּהִלּוֹת יִשְׂרָאֵל: בְּךָ בָּטְחוּ אֲבֹתֵינוּ, בָּטְחוּ וַתְּפַלְּטֵמוֹ: אֵלֶיךָ זָעֲקוּ וְנִמְלָטוּ, בְּךָ בָטְחוּ וְלֹא בוֹשׁוּ: וְאָנֹכִי תוֹלַעַת וְלֹא אִישׁ, חֶרְפַּת אָדָם וּבְזוּי עָם: כָּל רֹאַי יַלְעִגוּ לִי, יַפְטִירוּ בְשָׂפָה יָנִיעוּ רֹאשׁ: גֹּל אֶל יהוה יְפַלְּטֵהוּ, יַצִּילֵהוּ כִּי חָפֵץ בּוֹ: כִּי אַתָּה גֹחִי מִבָּטֶן, מַבְטִיחִי עַל שְׁדֵי אִמִּי: עָלֶיךָ הָשְׁלַכְתִּי מֵרָחֶם, מִבֶּטֶן אִמִּי אֵלִי אָתָּה אַל תִּרְחַק מִמֶּנִּי כִּי צָרָה קְרוֹבָה, כִּי אֵין עוֹזֵר: סְבָבוּנִי פָּרִים רַבִּים, אַבִּירֵי בָשָׁן כִּתְּרוּנִי: פָּצוּ עָלַי פִּיהֶם, אַרְיֵה טֹרֵף וְשֹׁאֵג: כַּמַּיִם נִשְׁפַּכְתִּי וְהִתְפָּרְדוּ כָּל עַצְמוֹתָי, הָיָה לִבִּי כַּדּוֹנָג, נָמֵס בְּתוֹךְ מֵעָי: יָבֵשׁ כַּחֶרֶשׂ כֹּחִי וּלְשׁוֹנִי מֻדְבָּק מַלְקוֹחָי, וְלַעֲפַר מָוֶת תִּשְׁפְּתֵנִי: כִּי סְבָבוּנִי כְּלָבִים, עֲדַת מְרֵעִים הִקִּיפוּנִי, כָּאֲרִי יָדַי וְרַגְלָי: אֲסַפֵּר כָּל עַצְמוֹתָי, הֵמָּה יַבִּיטוּ יִרְאוּ בִי: יְחַלְּקוּ בְגָדַי לָהֶם, וְעַל לְבוּשִׁי יַפִּילוּ גוֹרָל: וְאַתָּה יהוה אַל תִּרְחָק, אֱיָלוּתִי לְעֶזְרָתִי חוּשָׁה: הַצִּילָה מֵחֶרֶב נַפְשִׁי, מִיַּד כֶּלֶב יְחִידָתִי: הוֹשִׁיעֵנִי מִפִּי אַרְיֵה, וּמִקַּרְנֵי רֵמִים עֲנִיתָנִי: אֲסַפְּרָה שִׁמְךָ לְאֶחָי, בְּתוֹךְ קָהָל אֲהַלְלֶךָּ: יִרְאֵי יהוה הַלְלוּהוּ, כָּל זֶרַע יַעֲקֹב כַּבְּדוּהוּ, וְגוּרוּ מִמֶּנּוּ כָּל זֶרַע יִשְׂרָאֵל: כִּי לֹא בָזָה וְלֹא שִׁקַּץ עֱנוּת עָנִי, וְלֹא הִסְתִּיר פָּנָיו מִמֶּנּוּ, וּבְשַׁוְּעוֹ אֵלָיו שָׁמֵעַ: מֵאִתְּךָ תְהִלָּתִי בְּקָהָל רָב, נְדָרַי אֲשַׁלֵּם נֶגֶד יְרֵאָיו: יֹאכְלוּ עֲנָוִים וְיִשְׂבָּעוּ, יְהַלְלוּ יהוה דֹּרְשָׁיו, יְחִי לְבַבְכֶם לָעַד: יִזְכְּרוּ וְיָשֻׁבוּ אֶל יהוה כָּל אַפְסֵי אָרֶץ, וְיִשְׁתַּחֲווּ לְפָנֶיךָ כָּל מִשְׁפְּחוֹת גּוֹיִם: כִּי לַיהוה הַמְּלוּכָה, וּמֹשֵׁל בַּגּוֹיִם: אָכְלוּ וַיִּשְׁתַּחֲוּוּ כָּל דִּשְׁנֵי אֶרֶץ, לְפָנָיו יִכְרְעוּ כָּל יוֹרְדֵי עָפָר, וְנַפְשׁוֹ לֹא חִיָּה: זֶרַע יַעַבְדֶנּוּ, יְסֻפַּר לַאדֹנָי לַדּוֹר: יָבֹאוּ וְיַגִּידוּ צִדְקָתוֹ, לְעַם נוֹלָד כִּי עָשָׂה:","cond":["shirShelYomAtEnd","purim"]},{"kind":"special","text":"מזמור לתענית אסתר ולפורים:","cond":["shirShelYomAtEnd","ester"]},{"kind":"text","text":"לַמְנַצֵּחַ עַל אַיֶּלֶת הַשַּׁחַר, מִזְמוֹר לְדָוִד: אֵלִי אֵלִי לָמָה עֲזַבְתָּנִי, רָחוֹק מִישׁוּעָתִי דִּבְרֵי שַׁאֲגָתִי: אֱלֹהַי, אֶקְרָא יוֹמָם וְלֹא תַעֲנֶה, וְלַיְלָה וְלֹא דוּמִיָּה לִי: וְאַתָּה קָדוֹשׁ, יוֹשֵׁב תְּהִלּוֹת יִשְׂרָאֵל: בְּךָ בָּטְחוּ אֲבֹתֵינוּ, בָּטְחוּ וַתְּפַלְּטֵמוֹ: אֵלֶיךָ זָעֲקוּ וְנִמְלָטוּ, בְּךָ בָטְחוּ וְלֹא בוֹשׁוּ: וְאָנֹכִי תוֹלַעַת וְלֹא אִישׁ, חֶרְפַּת אָדָם וּבְזוּי עָם: כָּל רֹאַי יַלְעִגוּ לִי, יַפְטִירוּ בְשָׂפָה יָנִיעוּ רֹאשׁ: גֹּל אֶל יהוה יְפַלְּטֵהוּ, יַצִּילֵהוּ כִּי חָפֵץ בּוֹ: כִּי אַתָּה גֹחִי מִבָּטֶן, מַבְטִיחִי עַל שְׁדֵי אִמִּי: עָלֶיךָ הָשְׁלַכְתִּי מֵרָחֶם, מִבֶּטֶן אִמִּי אֵלִי אָתָּה אַל תִּרְחַק מִמֶּנִּי כִּי צָרָה קְרוֹבָה, כִּי אֵין עוֹזֵר: סְבָבוּנִי פָּרִים רַבִּים, אַבִּירֵי בָשָׁן כִּתְּרוּנִי: פָּצוּ עָלַי פִּיהֶם, אַרְיֵה טֹרֵף וְשֹׁאֵג: כַּמַּיִם נִשְׁפַּכְתִּי וְהִתְפָּרְדוּ כָּל עַצְמוֹתָי, הָיָה לִבִּי כַּדּוֹנָג, נָמֵס בְּתוֹךְ מֵעָי: יָבֵשׁ כַּחֶרֶשׂ כֹּחִי וּלְשׁוֹנִי מֻדְבָּק מַלְקוֹחָי, וְלַעֲפַר מָוֶת תִּשְׁפְּתֵנִי: כִּי סְבָבוּנִי כְּלָבִים, עֲדַת מְרֵעִים הִקִּיפוּנִי, כָּאֲרִי יָדַי וְרַגְלָי: אֲסַפֵּר כָּל עַצְמוֹתָי, הֵמָּה יַבִּיטוּ יִרְאוּ בִי: יְחַלְּקוּ בְגָדַי לָהֶם, וְעַל לְבוּשִׁי יַפִּילוּ גוֹרָל: וְאַתָּה יהוה אַל תִּרְחָק, אֱיָלוּתִי לְעֶזְרָתִי חוּשָׁה: הַצִּילָה מֵחֶרֶב נַפְשִׁי, מִיַּד כֶּלֶב יְחִידָתִי: הוֹשִׁיעֵנִי מִפִּי אַרְיֵה, וּמִקַּרְנֵי רֵמִים עֲנִיתָנִי: אֲסַפְּרָה שִׁמְךָ לְאֶחָי, בְּתוֹךְ קָהָל אֲהַלְלֶךָּ: יִרְאֵי יהוה הַלְלוּהוּ, כָּל זֶרַע יַעֲקֹב כַּבְּדוּהוּ, וְגוּרוּ מִמֶּנּוּ כָּל זֶרַע יִשְׂרָאֵל: כִּי לֹא בָזָה וְלֹא שִׁקַּץ עֱנוּת עָנִי, וְלֹא הִסְתִּיר פָּנָיו מִמֶּנּוּ, וּבְשַׁוְּעוֹ אֵלָיו שָׁמֵעַ: מֵאִתְּךָ תְהִלָּתִי בְּקָהָל רָב, נְדָרַי אֲשַׁלֵּם נֶגֶד יְרֵאָיו: יֹאכְלוּ עֲנָוִים וְיִשְׂבָּעוּ, יְהַלְלוּ יהוה דֹּרְשָׁיו, יְחִי לְבַבְכֶם לָעַד: יִזְכְּרוּ וְיָשֻׁבוּ אֶל יהוה כָּל אַפְסֵי אָרֶץ, וְיִשְׁתַּחֲווּ לְפָנֶיךָ כָּל מִשְׁפְּחוֹת גּוֹיִם: כִּי לַיהוה הַמְּלוּכָה, וּמֹשֵׁל בַּגּוֹיִם: אָכְלוּ וַיִּשְׁתַּחֲוּוּ כָּל דִּשְׁנֵי אֶרֶץ, לְפָנָיו יִכְרְעוּ כָּל יוֹרְדֵי עָפָר, וְנַפְשׁוֹ לֹא חִיָּה: זֶרַע יַעַבְדֶנּוּ, יְסֻפַּר לַאדֹנָי לַדּוֹר: יָבֹאוּ וְיַגִּידוּ צִדְקָתוֹ, לְעַם נוֹלָד כִּי עָשָׂה:","cond":["shirShelYomAtEnd","ester"]},{"kind":"special","text":"מזמור לחנוכה:","cond":["shirShelYomAtEnd","chanuka"]},{"kind":"text","text":"מִזְמוֹר שִׁיר חֲנֻכַּת הַבַּיִת לְדָוִד: אֲרוֹמִמְךָ יהוה כִּי דִלִּיתָנִי, וְלֹא שִׂמַּחְתָּ אֹיְבַי לִי: יהוה אֱלֹהָי שִׁוַּעְתִּי אֵלֶיךָ וַתִּרְפָּאֵנִי: יהוה, הֶעֱלִיתָ מִן שְׁאוֹל נַפְשִׁי, חִיִּיתַנִי מִיָּרְדִי בוֹר: זַמְּרוּ לַיהוה חֲסִידָיו וְהוֹדוּ לְזֵכֶר קָדְשׁוֹ: כִּי רֶגַע בְּאַפּוֹ חַיִּים בִּרְצוֹנוֹ, בָּעֶרֶב יָלִין בֶּכִי וְלַבֹּקֶר רִנָּה: וַאֲנִי אָמַרְתִּי בְשַׁלְוִי בַּל אֶמּוֹט לְעוֹלָם: יהוה בִּרְצוֹנְךָ הֶעֱמַדְתָּה לְהַרְרִי עֹז, הִסְתַּרְתָּ פָנֶיךָ הָיִיתִי נִבְהָל: אֵלֶיךָ יהוה אֶקְרָא וְאֶל אֲדֹנָי אֶתְחַנָּן: מַה בֶּצַע בְּדָמִי בְּרִדְתִּי אֶל שָׁחַת, הֲיוֹדְךָ עָפָר הֲיַגִּיד אֲמִתֶּךָ: שְׁמַע יהוה וְחָנֵּנִי, יהוה הֱיֵה עֹזֵר לִי: הָפַכְתָּ מִסְפְּדִי לְמָחוֹל לִי, פִּתַּחְתָּ שַׂקִּי וַתְּאַזְּרֵנִי שִׂמְחָה: לְמַעַן יְזַמֶּרְךָ כָבוֹד וְלֹא יִדֹּם, יהוה אֱלֹהַי לְעוֹלָם אוֹדֶךָּ:","cond":["shirShelYomAtEnd","chanuka"]},{"kind":"instruction","text":"קדיש יהא שלמא","cond":["shirShelYomAtEnd"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא, חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה וְשֵיזָבָא וּרְפוּאָה וּגְאֻלָּה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה, לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["shirShelYomAtEnd"]},{"kind":"text","text":"עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["shirShelYomAtEnd"]},{"kind":"instruction","text":"סוף התפילה","cond":["noTishaaBeav"]},{"kind":"text","text":"קַוֵּה אֶל יהוה, חֲזַק וְיַאֲמֵץ לִבֶּךָ, וְקַוֵּה אֶל יהוה: אֵין קָדוֹשׁ כַּיהוה כִּי אֵין בִּלְתֶּךָ, וְאֵין צוּר כֵּאלֹהֵינוּ: כִּי מִי אֱלוֹהַּ מִבַּלְעֲדֵי יהוה, וּמִי צוּר זוּלָתִי אֱלֹהֵינוּ:\n\nאֵין כֵּאלֹהֵינוּ, אֵין כַּאדוֹנֵנוּ, אֵין כְּמַלְכֵּנוּ, אֵין כְּמוֹשִׁיעֵנוּ. מִי כֵּאלֹהֵינוּ, מִי כַּאדוֹנֵנוּ, מִי כְּמַלְכֵּנוּ, מִי כְּמוֹשִׁיעֵנוּ. נוֹדֶה לֵאלֹהֵינוּ, נוֹדֶה לַאדוֹנֵנוּ, נוֹדֶה לְמַלְכֵּנוּ, נוֹדֶה לְמוֹשִׁיעֵנוּ. בָּרוּךְ אֱלֹהֵינוּ, בָּרוּךְ אֲדוֹנֵנוּ, בָּרוּךְ מַלְכֵּנוּ, בָּרוּךְ מוֹשִׁיעֵנוּ. אַתָּה הוּא אֱלֹהֵינוּ, אַתָּה הוּא אֲדוֹנֵנוּ, אַתָּה הוּא מַלְכֵּנוּ, אַתָּה הוּא מוֹשִׁיעֵנוּ. אַתָּה תוֹשִׁיעֵנוּ. אַתָּה תָקוּם תְּרַחֵם צִיּוֹן, כִּי עֵת לְחֶנְנָהּ, כִּי בָא מוֹעֵד:\n\nאַתָּה הוּא יהוה אֱלֹהֵינוּ שֶׁהִקְטִירוּ אֲבוֹתֵינוּ לְפָנֶיךָ אֶת קְטֹרֶת הַסַּמִּים, בִּזְמַן שֶׁבֵּית הַמִּקְדָּשׁ קַיָּם, כַּאֲשֶׁר צִוִּיתָ אוֹתָם עַל יַד מֹשֶׁה נְבִיאָךְ כַּכָּתוּב בְּתוֹרָתָךְ:\n\nוַיֹּאמֶר יהוה אֶל מֹשֶׁה, קַח לְךָ סַמִּים, נָטָף וּשְׁחֵלֶת וְחֶלְבְּנָה, סַמִּים, וּלְבֹנָה זַכָּה, בַּד בְּבַד יִהְיֶה: וְעָשִׂיתָ אֹתָהּ קְטֹרֶת, רֹקַח, מַעֲשֵׂה רוֹקֵחַ, מְמֻלָּח, טָהוֹר קֹדֶשׁ: וְשָׁחַקְתָּ מִמֶּנָּה הָדֵק, וְנָתַתָּה מִמֶּנָּה לִפְנֵי הָעֵדֻת בְּאֹהֶל מוֹעֵד, אֲשֶׁר אִוָּעֵד לְךָ שָׁמָּה, קֹדֶשׁ קָדָשִׁים תִּהְיֶה לָכֶם: וְנֶאֱמַר: וְהִקְטִיר עָלָיו אַהֲרֹן קְטֹרֶת סַמִּים, בַּבֹּקֶר בַּבֹּקֶר, בְּהֵיטִיבוֹ אֶת הַנֵּרֹת, יַקְטִירֶנָּה: וּבְהַעֲלֹת אַהֲרֹן אֶת הַנֵּרֹת בֵּין הָעֲרְבַּיִם, יַקְטִירֶנָּה, קְטֹרֶת תָּמִיד לִפְנֵי יהוה, לְדֹרֹתֵיכֶם:\n\nתָּנוּ רַבָּנָן: פִּטּוּם הַקְּטֹרֶת כֵּיצַד? שְׁלֹשׁ מֵאוֹת וְשִׁשִּׁים וּשְׁמוֹנָה מָנִים הָיוּ בָהּ, שְׁלֹשׁ מֵאוֹת וְשִׁשִּׁים וַחֲמִשָּׁה כְּמִנְיַן יְמוֹת הַחַמָּה מָנֶה בְכָל יוֹם, מַחֲצִיתוֹ בַבֹּקֶר וּמַחֲצִיתוֹ בַעָרֶב, וּשְׁלֹשָׁה מָנִים יְתֵרִים שֶׁמֵּהֶם מַכְנִיס כֹּהֵן גָּדוֹל וְנוֹטֵל מֵהֶם מָלֵא חָפְנָיו בְּיוֹם הָכִּיפוּרים, מַחֲזִירָן לְמַכְתֶּשֶׁת בְּעֶרֶב יוֹם הַכִּיפוּרִים כְּדֵי לְקַיֵּם מִצְוַת דַּקָּה מִן הַדַּקָּה, וְאַחַד עָשָׂר סַמָּנִים הָיוּ בָהּ וְאֵלּוּ הֵן:\n\nהַצֳּרִי וְהַצִּפּוֹרֶן וְהַחֶלְבְּנָה וְהַלְּבוֹנָה, מִשְׁקַל שִׁבְעִים שִׁבְעִים מָנֶה. מוֹר, וּקְצִיעָה וְשִׁבֹּלֶת נֵרְדְּ וְכַרְכֹּם, מִשְׁקַל שִׁשָּׁה עָשָׂר שִׁשָּׁה עָשָׂר מָנֶה. הַקֹשְׂט שְׁנֵים עָשָׂר, קִלּוּפָה שְׁלֹשָׁה, קִנָּמוֹן תִּשְׁעָה, בּוֹרִית כַּרְשִינָה תִּשְׁעָה קַבִּין, יֵין קַפְרִיסִין סְאִין תְּלָת וְקַבִּין תְּלָתָא, וְאִם לֹא מָצָא יֵין קַפְרִיסִין, מֵבִיא חֲמַר חִוָר עַתִּיק. מֶלַח סְדוֹמִית רוֹבַע, מַעֲלֶה עָשָׁן כָּל שֶׁהוּא. רִבִּי נָתַן הַבַּבְלִי אוֹמֵר: אַף כִּפַּת הַיַּרְדֵּן כָּל שֶׁהִיא, אִם נָתַן בָּהּ דְּבַשׁ פְּסָלָהּ, וְאִם חִסֵּר אַחַת מִכָּל סַמֲמָנֶיהָ, חַיָּב מִיתָה.\n\nרַבָּן שִׁמְעוֹן בֶּן גַּמְלִיאֵל אוֹמֵר: הַצֳּרִי אֵינוֹ אֶלָּא שְׁרָף הַנּוֹטֵף מֵעֲצֵי הַקְּטָף. בּוֹרִית כַּרְשִׁינָה לְמָה הִיא בָאָה? כְּדֵי לְשַׁפּוֹת בָּהּ אֶת הַצִּפּוֹרֶן, כְּדֵי שֶׁתְּהֵא נָאֶה. יַיִן קַפְרִיסִין לְמַה הוּא בָא? כְּדֵי לִשְׁרוֹת בּוֹ אֶת הַצִּפּוֹרֶן, כְּדֵי שֶׁתְּהֵא עַזָּה. וַהֲלֹא מִי רַגְלַיִם יָפִין לָהּ, אֶלָּא שֶׁאֵין מַכְנִיסִין מִי רַגְלַיִם בַּמִּקְדָּשׁ מִפְּנֵי הַכָּבוֹד.\n\nתַּנְיָא: רִבִּי נָתַן אוֹמֵר: כְּשֶׁהוּא שׁוֹחֵק, אוֹמֵר: \"הָדֵק הֵיטֵב, הֵיטֵב הָדֵק\", מִפְּנֵי שֶׁהַקּוֹל יָפֶה לַבְּשָׂמִים. פִּטְּמָהּ לַחֲצָאִין כְּשֵׁרָה, לְשָׁלִישׁ וּלְרָבִיעַ, לֹא שָׁמַעְנוּ. אָמַר רִבִּי יְהוּדָה: זֶה הַכְּלָל: אִם כְּמִדָּתָהּ - כְּשֵׁרָה לַחֲצָאִין, וְאִם חִסֵּר אַחַת מִכָּל סַמֲמָנֶיהָ, חַיָּב מִיתָה.\n\nתָּנֵי בַר קַפָּרָא: אַחַת לְשִׁשִּׁים אוֹ לְשִׁבְעִים שָׁנָה הָיְתָה בָּאָה שֶׁל שִׁירַיִם לַחֲצָאִין. וְעוֹד תָּנֵי בַר קַפָּרָא: אִלּוּ הָיָה נוֹתֵן בָּהּ קָרְטוֹב שֶׁל דְּבַשׁ, אֵין אָדָם יָכוֹל לַעֲמֹד מִפְּנֵי רֵיחָהּ. וְלָמָּה אֵין מְעָרְבִין בָּהּ דְּבַשׁ? מִפְּנֵי שֶׁהַתּוֹרָה אָמְרָה: כִּי כָל שְׂאֹר וְכָל דְּבַשׁ לֹא תַקְטִירוּ מִמֶּנּוּ אִשֶּׁה לַיהוה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה: יהוה צְבָאוֹת, אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ: וְעָרְבָה לַיהוה מִנְחַת יְהוּדָה וִירוּשָׁלִָם כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמֹנִיּוֹת:\n\nתָּנָא דְּבֵי אֵלִיָּהוּ: כָּל הַשּׁוֹנֶה הֲלָכוֹת בְּכָל יוֹם, מֻבְטָח לוֹ שֶׁהוּא בֶּן הָעוֹלָם הַבָּא, שֶׁנֶּאֱמַר: \"הֲלִיכוֹת עוֹלָם לוֹ:\" אֶל תִּקְרֵי \"הֲלִיכוֹת\", אֶלָּא \"הֲלָכוֹת\". אָמַר רִבִּי אֶלְעָזָר אָמַר רִבִּי חֲנִינָא: תַּלְמִידֵי חֲכָמִים מַרְבִּים שָׁלוֹם בָּעוֹלָם, שֶׁנֶּאֱמַר: \"וְכָל בָּנַיִךָ לִמּוּדֵי יהוה, וְרַב שְׁלוֹם בָּנָיִךָ:\" אֶל תִּקְרֵי \"בָנַיִךְ\" אֶלָּא \"בוֹנָיִךְ\". יְהִי שָׁלוֹם בְּחֵילֵךְ שַׁלְוָה בְּאַרְמְנוֹתָיִךְ: לְמַעַן אָחַי וְרֵעָי אֲדַבְּרָה נָא שָׁלוֹם בָּךְ: לְמַעַן בֵּית יהוה אֱלֹהֵינוּ אֲבַקְשָׁה טוֹב לְךָ: וּרְאֵה בָנִים לְבָנֶיךָ שָׁלוֹם עַל יִשְׂרָאֵל: שָׁלוֹם רַב לְאֹהֲבֵי תּוֹרָתֶךְ וְאֵין לָמוֹ מִכְשׁוֹל: יהוה, עֹז לְעַמּוֹ יִתֵּן, יהוה יְבָרֵךְ אֶת עַמּוֹ בַשָׁלוֹם:","cond":["noTishaaBeav"]},{"kind":"instruction","text":"קדיש על ישראל","cond":["noTishaaBeav"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.\nעַל יִשְׂרָאֵל וְעַל רַבָּנָן וְעַל תַּלְמִידֵיהוֹן וְעַל כָּל תַּלְמִידֵי תַלְמִידֵיהוֹן, דְּעָסְקִין בְּאוֹרַיְתָא קַדִּישְׁתָּא, דִּי בְאַתְרָא הָדֵין וְדִי בְכָל אֲתַר וַאֲתַר, יְהֵא לָנָא וּלְכוֹן וּלְהוֹן, חִנָּא וְחִסְדָּא וְרַחֲמֵי, מִן קֳדָם אֱלָהָא מָארֵי שְׁמַיָּא וְאַרְעָא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא, חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה וְשֵיזָבָא וּרְפוּאָה וּגְאֻלָּה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה, לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noTishaaBeav"]},{"kind":"text","text":"עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noTishaaBeav"]},{"kind":"instruction","text":"חזן:","cond":[]},{"kind":"text","text":"בָּרְכוּ אֶת יהוה הַמְבֹרָךְ.","cond":[]},{"kind":"instruction","text":"קהל וחזן:","cond":[]},{"kind":"text","text":"בָּרוּךְ יהוה הַמְבֹרָךְ לְעוֹלָם וָעֶד.","cond":[]},{"kind":"header","text":"עלינו לשבח","cond":[]},{"kind":"text","text":"עָלֵינוּ לְשַׁבֵּחַ לַאֲדוֹן הַכֹּל, לָתֵת גְּדֻלָּה לְיוֹצֵר בְּרֵאשִׁית, שֶׁלֹּא עָשָׂנוּ כְּגוֹיֵי הָאֲרָצוֹת וְלֹא שָׂמָנוּ כְּמִשְׁפְּחוֹת הָאֲדָמָה, שֶׁלֹּא שָׂם חֶלְקֵנוּ כָּהֶם וְגוֹרָלֵנוּ כְּכָל הֲמוֹנָם, שֶׁהֵם מִשְׁתַּחֲוִים לָהֶבֶל וָרִיק וּמִתְפַּלְּלִים אֶל אֵל לֹא יוֹשִׁיעַ, וַאֲנַחְנוּ מִשְׁתַּחֲוִים לִפְנֵי מֶלֶךְ מַלְכֵי הַמְּלָכִים הַקָּדוֹשׁ בָּרוּךְ הוּא, שֶׁהוּא נוֹטֶה שָׁמַיִם וְיוֹסֵד אָרֶץ, וּמוֹשַׁב יְקָרוֹ בַּשָּׁמַיִם מִמַּעַל, וּשְׁכִינַת עֻזּוֹ בְּגָבְהֵי מְרוֹמִים. הוּא אֱלֹהֵינוּ וְאֵין עוֹד אַחֵר. אֱמֶת מַלְכֵּנוּ וְאֶפֶס זוּלָתוֹ, כַּכָּתוּב בַּתּוֹרָה: וְיָדַעְתָּ הַיּוֹם וַהֲשֵׁבוֹתָ אֶל לְבָבֶךָ כִּי יהוה הוּא הָאֱלֹהִים בַּשָּׁמַיִם מִמַּעַל וְעַל הָאָרֶץ מִתָּחַת, אֵין עוֹד:","cond":[]},{"kind":"text","text":"עַל כֵּן נְקַוֶּה לָךְ יהוה אֱלֹהֵינוּ לִרְאוֹת מְהֵרָה בְּתִפְאֶרֶת עֻזָּךְ לְהַעֲבִיר גִּלּוּלִים מִן הָאָרֶץ וְהָאֱלִילִים כָּרוֹת יִכָּרֵתוּן, לְתַקֵּן עוֹלָם בְּמַלְכוּת שַׁדַּי, וְכָל בְּנֵי בָשָׂר יִקְרְאוּ בִשְׁמֶךָ לְהַפְנוֹת אֵלֶיךָ כָּל רִשְׁעֵי אָרֶץ. יַכִּירוּ וְיֵדְעוּ כָּל יוֹשְׁבֵי תֵבֵל כִּי לְךָ תִכְרַע כָּל בֶּרֶךְ, תִּשָּׁבַע כָּל לָשׁוֹן. לְפָנֶיךָ יהוה אֱלֹהֵינוּ יִכְרְעוּ וְיִפֹּלוּ וְלִכְבוֹד שִׁמְךָ יְקָר יִתֵּנוּ, וִיקַבְּלוּ כֻלָּם אֶת עוֹל מַלְכוּתֶךָ, וְתִמְלוֹךְ עֲלֵיהֶם מְהֵרָה לְעוֹלָם וָעֶד. כִּי הַמַּלְכוּת שֶׁלְּךָ הִיא, וּלְעוֹלְמֵי עַד תִּמְלוֹךְ בְּכָבוד, כַּכָּתוּב בְּתוֹרָתָךְ: יהוה יִמְלֹךְ לְעֹלָם וָעֶד: וְנֶאֱמַר: וְהָיָה יהוה לְמֶלֶךְ עַל כָּל הָאָרֶץ, בַּיּום הַהוּא יִהְיֶה יהוה אֶחָד וּשְׁמוֹ אֶחָד:","cond":[]},{"kind":"instruction","text":"טוב לומר אחר התפילה פסוקים אלה:","cond":[]},{"kind":"text","text":"וַיֹּאמֶר: אִם שָׁמוֹע תִּשְׁמַע לְקוֹל יהוה אֱלֹהֶיךָ וְהַיּשָׁר בְּעֵינָיו תַּעֲשֶׂה וְהַאֲזַנְתָּ לְמִצְוׂתָיו וְשָׁמַרְתָּ כָּל חֻקָּיו, כָּל הַמַּחֲלָה אֲשֶׁר שַׂמְתִּי בְמִצְרַיִם לֹא אָשִׂים עָלֶיךָ, כִּי אֲנִי יהוה רֹפְאֶיךָ: עֵץ חַיִּים הִיא לַמַּחֲזִיקִים בָּהּ, וְתֹמְכֶיהָ מְאֻשָּׁר: דְּרָכֶיהָ דַרְכֵי נֹעַם, וְכָל נְתִיבוֹתֶיהָ שָׁלוֹם: מִגְדַּל עֹז שֵׁם יהוה, בּוֹ יָרוּץ צַדִּיק וְנִשְׂגָּב: כִּי בִי יִרְבּוּ יָמֶיךָ וְיוֹסִיפוּ לְךָ שְׁנוֹת חַיִּים:","cond":[]},{"kind":"instruction","text":"יש נוהגים לומר אחר התפילה מזמור זה:","cond":[]},{"kind":"text","text":"לְדָוִד, יהוה אוֹרִי וְיִשְׁעִי מִמִּי אִירָא, יהוה מָעוֹז חַיַּי מִמִּי אֶפְחָד: בִּקְרֹב עָלַי מְרֵעִים לֶאֱכֹל אֶת בְּשָׂרִי, צָרַי וְאֹיְבַי לִי, הֵמָּה כָשְׁלוּ וְנָפָלוּ: אִם תַחֲנֶה עָלַי מַחֲנֶה לֹא יִירָא לִבִּי, אִם תָּקוּם עָלַי מִלְחָמָה בְּזֹאת אֲנִי בוֹטֵחַ: אַחַת שָאַלְתִּי מֵאֵת יהוה, אוֹתָהּ אֲבַקֵּשׁ, שִׁבְתִּי בְּבֵית יהוה כָּל יְמֵי חַיַּי, לַחֲזוֹת בְּנֹעַם יהוה וּלְבַקֵּר בְּהֵיכָלוֹ: כִּי יִצְפְּנֵנִי בְּסֻכֹּה בְּיוֹם רָעָה יַסְתִּירֵנִי בְּסֵתֶר אָהֳלוֹ, בְּצוּר יְרוֹמְמֵנִי: וְעַתָּה יָרוּם רֹאשִׁי עַל אֹיְבַי סְבִיבוֹתַי, וְאֶזְבְּחָה בְאָהֳלוֹ זִבְחֵי תְרוּעָה, אָשִׁירָה וַאֲזַמְּרָה לַיהוה: שְׁמַע יהוה קוֹלִי אֶקְרָא, וְחָנֵּנִי וַעֲנֵנִי: לְךָ אָמַר לִבִּי בַּקְּשׁוּ פָנַי, אֶת פָּנֶיךָ יהוה אֲבַקֵּשׁ: אַל תַּסְתֵּר פָּנֶיךָ מִמֶּנִּי, אַל תַּט בְּאַף עַבְדֶּךָ, עֶזְרָתִי הָיִיתָ, אַל תִּטְּשֵׁנִי וְאַל תַּעַזְבֵנִי אֱלֹהֵי יִשְׁעִי: כִּי אָבִי וְאִמִּי עֲזָבוּנִי, וַיהוה יַאַסְפֵנִי: הוֹרֵנִי יהוה דַּרְכֶּךָ וּנְחֵנִי בְּאֹרַח מִישׁוֹר לְמַעַן שׁוֹרְרָי: אַל תִּתְּנֵנִי בְּנֶפֶשׁ צָרָי, כִּי קָמוּ בִי עֵדֵי שֶׁקֶר וִיפֵחַ חָמָס: לוּלֵא הֶאֱמַנְתִּי לִרְאוֹת בְּטוּב יהוה בְּאֶרֶץ חַיִּים: קַוֵּה אֶל יהוה, חֲזַק וְיַאֲמֵץ לִבֶּךָ, וְקַוֵּה אֶל יהוה:","cond":[]},{"kind":"instruction","text":"קדיש יהא שלמא","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא, חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה וְשֵיזָבָא וּרְפוּאָה וּגְאֻלָּה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה, לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"header","text":"י\"ג עיקרים","cond":[]},{"kind":"instruction","text":"יג עיקרים","cond":[]},{"kind":"text","text":"הֲרֵינִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה בִּשְׁלֹשָׁה עָשָׂר עִקָּרִים שֶׁל הַתּוֹרָה הַקְּדוֹשָׁה: \nא. קָּדוֹשׁ בָּרוּךְ הוּא נִמְצָא וּמַשְׁגִּיחַ,\nב. וְהוּא אֶחָד,\nג. וְאֵין לוֹ גּוּף וְאֵין לוֹ דְּמוּת הַגּוּף,\nד. וְשֶׁהוּא קַדְמוֹן לְכָל קְדוּמִים,\nה. וְאֵין עֲבוֹדָה לְזוּלָתוֹ,\nו. וְיוֹדֵעַ מַחְשְׁבוֹת בְּנֵי אָדָם,\nז. וְשֶהַנְּבוּאָה אֱמֶת,\nח. וְשֶׁמֹּשֶׁה רַבֵּינוּ עָלָיו הַשָּׁלוֹם הוּא אֲדוֹן לְכָל הַנְּבִיאִים,\nט. וְשֶׁהַתּוֹרָה כֻּלָּהּ נְתוּנָה מִן הַשָּׁמַיִם,\nי. וְשֶׁלֹּא תִּשְׁתַּנֶּה בְּשׁוּם זְמַן חַס וְשָׁלוֹם,\nיא. וְשֶׁהַקָּדוֹשׁ בָּרוּךְ הוּא מַעֲנִישׁ לָרְשָׁעִים וּמְשַׁלֵּם שָׂכָר טוֹב לַצַּדִּיקִים,\nיב. וְשֶׁיָּבוֹא מֶלֶךְ הַמָּשִׁיחַ,\nיג. וְשֶׁהַמֵּתִים עֲתִידִים לִחְיוֹת.\nיְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבֹתֵינוּ, שֶׁתָּכֹף יִצְרֵנוּ לַעֲבוֹדָתֶךָ כָּל יְמֵי חַיֵּינוּ תָּמִיד, אָמֵן כֵּן יְהִי רָצוֹן.","cond":[]},{"kind":"header","text":"עשר זכירות","cond":[]},{"kind":"instruction","text":"עשר זכירות","cond":[]},{"kind":"text","text":"לְשֵׁם יִחוּד קֻדְשָׁא בְרִיךְ הוּא וּשְכִינְתֵּהּ, הֲרֵינִי בָא לְקַיֵּם מִצְוַת עֶשֶׂר זְכִירוֹת שֶׁחַיָּב אָדָם לִזְכּוֹר בְּכָל יוֹם, וְאֵלּוּ הֵן:\nא. יְצִיאַת מִצְרַיִם,\nב. הַשַּׁבָּת,\nג. הַמָּן,\nד. מַעֲשֵׂה עֲמָלֵק הָרָשָׁע,\nה. מַעֲמָד הַר סִינַי,\nו. מַה שֶּׁהִקְצִיפוּ אֲבוֹתֵינוּ לַקָּדוֹשׁ בָּרוּךְ הוּא בַּמִּדְבָּר וּבִפְרָט בָּעֵגֶל,\nז. מַה שֶּׁיָּעֲצוּ בָּלָק וּבִלְעָם לַעֲשׂוֹת לַאֲבוֹתֵינוּ לְמַעַן דַּעַת צִדְקוֹת ה',\nח. מַעֲשֵׂה מִרְיָם הַנְּבִיאָה,\nט. מִצְוַת \"וְזָכַרְתָּ אֶת ה' אֱלֹקֶיךָ כִּי הוּא הַנּוֹתֵן לְךָ כֹּחַ לַעֲשׂוֹת חַיִל\",\nי. וּזְכִירַת יְרוּשָׁלַיִם תִּבָּנֶה וְתִכּוֹנֵן בִּמְהֵרָה בְיָמֵינוּ, אָמֵן.","cond":[]}],"mincha":[{"kind":"header","text":"הנחת תפילין","cond":["tishaaBeav"]},{"kind":"instruction","text":"מתעטפים בטלית ומניחים תפילין, ואומרים קריאת שמע. ויש אומרים שעדיף שלא לומר קריאת שמע מפני איסור לימוד תורה.","cond":["tishaaBeav"]},{"kind":"text","text":"שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:","cond":["tishaaBeav"]},{"kind":"instruction","text":"בלחש:","cond":["tishaaBeav"]},{"kind":"text","text":"בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד.\n\nוְאָהַבְתָּ אֵת יהוה אֱלֹהֶיךָ, בְּכָל לְבָבְךָ וּבְכָל נַפְשְׁךָ וּבְכָל מְאֹדֶךָ: וְהָיוּ הַדְּבָרִים הָאֵלֶּה אֲשֶׁר אָנֹכִי מְצַוְּךָ הַיּוֹם, עַל לְבָבֶךָ: וְשִׁנַּנְתָּם לְבָנֶיךָ וְדִבַּרְתָּ בָּם, בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ: וּקְשַׁרְתָּם לְאוֹת עַל יָדֶךָ, וְהָיוּ לְטֹטָפֹת בֵּין עֵינֶיךָ: וּכְתַבְתָּם עַל מְזֻזוֹת בֵּיתֶךָ וּבִשְׁעָרֶיךָ:","cond":["tishaaBeav"]},{"kind":"text","text":"וְהָיָה אִם שָׁמֹעַ תִּשְׁמְעוּ אֶל מִצְוׂתַי, אֲשֶׁר אָנֹכִי מְצַוֶּה אֶתְכֶם הַיּוֹם, לְאַהֲבָה אֶת יהוה אֱלֹהֵיכֶם וּלְעָבְדוֹ, בְּכָל לְבַבְכֶם וּבְכָל נַפְשְׁכֶם: וְנָתַתִּי מְטַר אַרְצְכֶם בְּעִתּוֹ, יוֹרֶה וּמַלְקוֹשׁ, וְאָסַפְתָּ דְגָנֶךָ וְתִירֹשְׁךָ וְיִצְהָרֶךָ: וְנָתַתִּי עֵשֶׂב בְּשָׂדְךָ לִבְהֶמְתֶּךָ, וְאָכַלְתָּ וְשָׂבָעְתָּ: הִשָּׁמְרוּ לָכֶם פֶּן יִפְתֶּה לְבַבְכֶם, וְסַרְתֶּם וַעֲבַדְתֶּם אֱלֹהִים אֲחֵרִים וְהִשְׁתַּחֲוִיתֶם לָהֶם: וְחָרָה אַף יהוה בָּכֶם, וְעָצַר אֶת הַשָּׁמַיִם וְלֹא יִהְיֶה מָטָר, וְהָאֲדָמָה לֹא תִתֵּן אֶת יְבוּלָהּ, וַאֲבַדְתֶּם מְהֵרָה מֵעַל הָאָרֶץ הַטֹּבָה אֲשֶׁר יהוה נֹתֵן לָכֶם: וְשַׂמְתֶּם אֶת דְּבָרַי אֵלֶּה עַל לְבַבְכֶם וְעַל נַפְשְׁכֶם, וּקְשַׁרְתֶּם אֹתָם לְאוֹת עַל יֶדְכֶם וְהָיוּ לְטוֹטָפֹת בֵּין עֵינֵיכֶם: וְלִמַּדְתֶּם אֹתָם אֶת בְּנֵיכֶם לְדַבֵּר בָּם, בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ: וּכְתַבְתָּם עַל מְזוּזוֹת בֵּיתֶךָ וּבִשְׁעָרֶיךָ: לְמַעַן יִרְבּוּ יְמֵיכֶם וִימֵי בְנֵיכֶם עַל הָאֲדָמָה אֲשֶׁר נִשְׁבַּע יהוה לַאֲבֹתֵיכֶם לָתֵת לָהֶם, כִּימֵי הַשָּׁמַיִם עַל הָאָרֶץ:","cond":["tishaaBeav"]},{"kind":"text","text":"וַיֹּאמֶר יהוה אֶל מֹשֶׁה לֵּאמֹר: דַּבֵּר אֶל בְּנֵי יִשְׂרָאֵל וְאָמַרְתָּ אֲלֵהֶם, וְעָשׂוּ לָהֶם צִיצִת עַל כַּנְפֵי בִגְדֵיהֶם לְדֹרֹתָם, וְנָתְנוּ עַל צִיצִת הַכָּנָף פְּתִיל תְּכֵלֶת: וְהָיָה לָכֶם לְצִיצִת, וּרְאִיתֶם אֹתוֹ, וּזְכַרְתֶּם אֶת כָּל מִצְוׂת יהוה וַעֲשִׂיתֶם אֹתָם, וְלֹא תָתֻרוּ אַחֲרֵי לְבַבְכֶם וְאַחֲרֵי עֵינֵיכֶם אֲשֶׁר אַתֶּם זֹנִים אַחֲרֵיהֶם: לְמַעַן תִּזְכְּרוּ וַעֲשִׂיתֶם אֶת כָּל מִצְוׂתָי, וִהְיִיתֶם קְדֹשִׁים לֵאלֹהֵיכֶם: אֲנִי יהוה אֱלֹהֵיכֶם אֲשֶׁר הוֹצֵאתִי אֶתְכֶם מֵאֶרֶץ מִצְרַיִם, לִהְיוֹת לָכֶם לֵאלֹהִים, אֲנִי יהוה אֱלֹהֵיכֶם:","cond":["tishaaBeav"]},{"kind":"text","text":"אֱמֶת.","cond":["tishaaBeav"]},{"kind":"header","text":"פתיחת אליהו","cond":[]},{"kind":"instruction","text":"פתיחת אליהו הנביא זכור לטוב:\n\nטוב לומר קודם כל תפילה פתיחת אליהו ז\"ל, ומועילה לפתיחת הלב:","cond":[]},{"kind":"text","text":"וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ:\nפָּתַח אֵלִיָּהוּ הַנָּבִיא זָכוּר לַטּוֹב וְאָמַר: רִבּוֹן עָלְמִין דְּאַנְתְּ הוּא חָד וְלָא בְּחֻשְׁבָּן. אַנְתְּ הוּא עִלָּאָה עַל כָּל עִלָּאִין סְתִימָא עַל כָּל סְתִימִין לֵית מַחֲשָׁבָה תְּפִיסָא בָּךְ כְּלָל. אַנְתְּ הוּא דְּאַפַּקְתְּ עֶשֶׂר תִּקּוּנִין וְקָרֵינָן לוֹן עֶשֶׂר סְפִירָן לְאַנְהָגָא בְהוֹן עָלְמִין סְתִימִין דְּלָא אִתְגַּלְיָן וְעָלְמִין דְּאִתְגַּלְיָן. וּבְהוֹן אִתְכַּסִּיאַת מִבְּנֵי נָשָׁא. וְאַנְתְּ הוּא דְקָשִׁיר לוֹן וּמְיַחֵד לוֹן. וּבְגִין דְּאַנְתְּ מִלְּגָאו כָּל מָאן דְּאַפְרִישׁ חַד מִן חַבְרֵיהּ מֵאִלֵּין עֶשֶׂר אִתְחַשִׁיב לֵיהּ כְּאִלּוּ אַפְרִישׁ בָּךְ. וְאִלֵּין עֶשֶׂר סְפִירָן אִנּוּן אַזְלִין כְּסִדְרָן חַד אָרִיךְ וְחָד קָצֵר וְחַד בֵּינונִי. וְאַנְתְּ הוּא דְּאַנְהִיג לוֹן. וְלֵית מָאן דְּאַנְהִיג לָךְ לָא לְעֵילָּא וְלָא לְתַתָּא וְלָא מִכָּל סִטְרָא. לְבוּשִׁין תַּקַּנְתְּ לוֹן דְּמִנַּיְהוּ פַרְחִין נִשְׁמָתִין לִבְנֵי נָשָׁא. וְכַמָּה גוּפִין תַּקַּנְתְּ לוֹן דְּאִתְקְרִיאוּ גוּפָא לְגַבֵּי לְבוּשִׁין דִּמְכַסְיָן עֲלֵיהון וְאִתְקְרִיאוּ בְּתִקּוּנָא דָא. חֶסֶד דְּרוֹעָא יְמִינָא. גְּבוּרָה דְרוֹעָא שְׂמָאלָא. תִּפְאֶרֶת גּוּפָא. נֶצַח וְהוֹד תְּרֵין שׁוֹקִין. יְסוֹד סִיּוּמָא דְּגוּפָא אוֹת בְּרִית קֹדֶשׁ. מַלְכוּת פֶּה תּוֹרָה שֶׁבְּעַל פֶּה קָרֵינָן לָהּ. חָכְמָה מוֹחָא אִיהִי מַחֲשָׁבָה מִלְּגָאו. בִּינָה לִבָּא וּבָהּ הַלֵּב מֵבִין. וְעַל אִלֵּין תְּרֵין כְּתִיב \"הַנִּסְתָּרות לַיהוה אֱלֹהֵינוּ\". כֶּתֶר עֶלְיוֹן אִיהוּ כֶּתֶר מַלְכוּת. וְעָלֵיהּ אִתְמַר \"מַגִּיד מֵרֵאשִׁית אַחֲרִית\". וְאִיהוּ קַרְקַפְתָּא דִתְפִלֵּי. מִלְּגָאו אִיהוּ אוֹת יוֹ\"ד אוֹת הֵ\"א אוֹת וָא\"ו וְאוֹת הֵ\"א דְּאִיהוּ אֹרַח אֲצִילוּת. אִיהוּ שַׁקְיוּ דְּאִילָנָא בִּדְרוֹעוֹי וְעַנְפּוֹי. כְּמַיָּא דְאַשְׁקֵי לְאִילָנָא וְאִתְרַבֵּי בְּהַהוּא שַׁקְיוּ.\n\nרִבּוֹן עָלְמִין אַנְתְּ הוּא עִלַּת הָעִלּוֹת וְסִבַּת הַסִּבּוֹת דְאַשְׁקֵי לְאִילָנָא בְּהַהוּא נְבִיעוּ. וְהַהוּא נְבִיעוּ אִיהוּ כְּנִשְׁמְתָא לְגוּפָא דְּאִיהוּ חַיִּים לְגוּפָא. וּבָךְ לֵית דִּמְיוֹן וְלֵית דִּיּוּקְנָא (דְּגוּפָא) מִכָּל מַה דִלְגָאו וּלְבַר. וּבָרָאתָ שְׁמַיָּא וְאַרְעָא. וְאַפַּקְתְּ מִנְּהוֹן שִׁמְשָׁא וְסִיהֲרָא וְכוֹכְבַיָּא וּמַזָּלֵי. וּבְאַרְעָא אִילָנִין וּדְשָׁאִין וְגִנְּתָא דְעֵדֶן וְעִשְׂבִּין וְחֵיוָן וְעוֹפִין וְנוּנִין וּבְעִירִין וּבְנֵי נָשָׁא. לְאִשְׁתְּמוֹדְעָא בְּהוֹן עִלָּאִין וְאֵיךְ יִתְנַהֲגוּן בְּהוֹן עִלָּאִין וְתַתָּאִין. וְאֵיךְ אִשְׁתְּמוֹדְעָן מֵעִלָּאֵי וְתַתָּאֵי וְלֵית דְּיָדַע בָּךְ כְּלָל. וּבַר מִנָּךְ לֵית יִחוּדָא בְּעִלָּאֵי וְתַתָּאֵי. וְאַנְתְּ אִשְׁתְּמוֹדָע אָדוֹן עַל כֹּלָּא. וְכָל סְפִירָן כָּל חַד אִית לֵיהּ שֵׁם יְדִיעַ. וּבְהוֹן אִתְקְרִיאוּ מַלְאָכַיָּא. וְאַנְתְּ לֵית לָךְ שֵׁם יְדִיעַ דְּאַנְתְּ הוּא מְמַלֵּא כָּל שְׁמָהָן וְאַנְתְּ הוּא שְׁלִימוּ דְּכֻלְהוּ. וְכַד אַנְתְּ תִּסְתַּלָּק מִנְּהוֹן. אִשְׁתְּאָרוּ כֻּלְּהוּ שְׁמָהָן כְּגוּפָא בְלָא נִשְׁמָתָא. אַנְתְּ חַכִּים וְלָאו בְּחָכְמָה יְדִיעָא. אַנְתְּ הוּא מֵבִין וְלָאו מִבִּינָה יְדִיעָא. לֵית לָךְ אֲתָר יְדִיעָא. אֶלָּא לְאִשְׁתְּמוֹדְעָא תָּקְפָּךְ וְחֵילָךְ לִבְנֵי נָשָׁא. וּלְאַחְזָאָה לוֹן אֵיךְ אִתְנְהִיג עָלְמָא בְדִינָא וּבְרַחֲמֵי דְאִינוּן צֶדֶק וּמִשְׁפָּט כְּפוּם עוֹבָדֵיהוֹן דִּבְנֵי נָשָׁא. דִּין אִיהוּ גְבוּרָה. מִשְׁפָּט עַמּוּדָא דְאֶמְצָעִיתָא. צֶדֶק מַלְכוּתָא קַדִּישָׁא מֹאזְנֵי צֶדֶק תְּרֵין סַמְכֵי קְשׁוֹט. הִין צֶדֶק אוֹת בְּרִית. כֹּלָּא לְאַחְזָאָה אֵיךְ אִתְנְהִיג עָלְמָא. אֲבָל לָאו דְּאִית לָךְ צֶדֶק יְדִיעָא דְּאִיהוּ דִין. וְלָאו מִשְׁפָּט יְדִיעָא דְאִיהוּ רַחֲמֵי. וְלָאו מִכָּל אִלֵּין מִדּוֹת כְּלָל. קוּם רִבִּי שִׁמְעון וְיִתְחַדְּשׁוּן מִלִּין עַל יְדָךְ. דְהָא רְשׁוּתָא אִית לָךְ לְגַלָּאָה רָזִין טְמִירִין עַל יְדָךְ מַה דְלָא אִתְיְהִיב רְשׁוּ לְגַלָּאָה לְשׁוּם בַּר נָשׁ עַד כְּעָן.\n\nקָם רִבִּי שִׁמְעון פָּתַח וְאָמַר: לְךָ יהוה הַגְּדֻלָּה וְהַגְּבוּרָה וְהַתִּפְאֶרֶת וְהַנֵּצַח וְהַהוֹד כִּי כֹל בַּשָּׁמַיִם וּבָאָרֶץ: לְךָ יהוה הַמַּמְלָכָה, וְהַמִּתְנַשֵּׂא לְכֹל עִלָּאִין שְׁמָעוּ אִנּוּן דְּמִיכִין דְּחֶבְרוֹן וְרַעְיָא מְהֵימְנָא אִתְּעָרוּ מִשְּׁנַתְכוֹן. הָקִיצוּ וְרַנְּנוּ שׁוֹכְנֵי עָפָר. אִלֵּין אִנּוּן צַדִּיקַיָּא דְּאִנּוּן מִסִּטְרָא דְהַהוּא דְּאִתְמַר בָּהּ \"אֲנִי יְשֵׁנָה וְלִבִּי עֵר\". וְלָאו אִנּוּן מֵתִים. וּבְגִין דָּא אִתְּמַר בְּהוֹן \"הָקִיצוּ וְרַנְּנוּ\" וְגו'. רַעְיָא מְהֵימְנָא אַנְתְּ וַאֲבָהָן הָקִיצוּ וְרַנְּנוּ לְאִתְּעָרוּתָא דִּשְׁכִינְתָּא דְּאִיהִי יְשֵׁנָה בְגָלוּתָא. דְּעַד כְּעַן צַדִּיקַיָּא כֻּלְּהוּ דְמִיכִין וְשִׁנְתָּא בְחוֹרֵיהוֹן. מִיָּד יָהִיבַת שְׁכִינְתָּא תְּלַת קָלִין לְגַבֵּי רַעְיָא מְהֵימְנָא וְיִימָא לֵיהּ: קוּם רַעְיָא מְהֵימְנָא - דְהָא עֲלָךְ אִתְּמַר \"קוֹל דּוֹדִי דוֹפֵק\" לְגַבָּאי בְּאַרְבָּע אַתְוָן דִּילֵיהּ. וְיִימָא בְהוֹן \"פִּתְחִי לִי אֲחותִי רַעְיָתִי יוֹנָתִי תַמָּתִי\". דְהָא תַּם עֲוׂנֵךְ בַּת צִיּוֹן לֹא יוֹסִיף לְהַגְלוֹתֵךְ. שֶׁרֹּאשִׁי נִמְלָא טָל. מַאי \"נִמְלָא טָל\"? אֶלָּא אָמַר קֻדְשָׁא בְרִיךְ הוּא, אַנְתְּ חָשַׁבְתְּ דְּמִיּוֹמָא דְאִתְחָרַב בֵּי מַקְדְּשָׁא דְּעָאלְנָא בְּבֵיתָא דִילִי וְעָאלְנָא בְיִשּׁוּבָא, לָאו הֲכִי, דְּלָא עָאלְנָא כָּל זִמְנָא דְּאַנְתְּ בְּגָלוּתָא. הֲרֵי לָךְ סִימָנָא: שֶׁרֹּאשִׁי נִמְלָא טָל, הֵ\"א שְׁכִינְתָא בְּגָלוּתָא. שְׁלִימוּ דִילָהּ וְחַיִּים דִּילָהּ אִיהוּ טַל. וְדָא אִיהוּ אוֹת יוֹ\"ד אוֹת הֵ\"א אוֹת וָא\"ו וְאוֹת הֵ\"א אִיהִי שְׁכִינְתָּא דְלָא מֵחֻשְׁבָּן ט\"ל, אֶלָּא אוֹת יוֹ\"ד אוֹת הֵ\"א וְאוֹת וָא\"ו דִּסְלִיקוּ אַתְוָן לְחֻשְׁבָּן טָ\"ל. דְּאִיהִי מַלְיָא לִשְׁכִינְתָּא מִנְּבִיעוּ דְּכָל מְקוֹרִין עִלָּאִין. מִיַּד קָם רַעְיָא מְהֵימְנָא וַאֲבָהָן קַדִּישִׁין עִמֵּיהּ. עַד כָּאן רָזָא דְיִחוּדָא. בָּרוּךְ יהוה לְעוֹלָם אָמֵן וְאָמֵן:","cond":[]},{"kind":"instruction","text":"קדיש על ישראל","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.\nעַל יִשְׂרָאֵל וְעַל רַבָּנָן וְעַל תַּלְמִידֵיהוֹן וְעַל כָּל תַּלְמִידֵי תַלְמִידֵיהוֹן, דְּעָסְקִין בְּאוֹרַיְתָא קַדִּישְׁתָּא, דִּי בְאַתְרָא הָדֵין וְדִי בְכָל אֲתַר וַאֲתַר, יְהֵא לָנָא וּלְכוֹן וּלְהוֹן, חִנָּא וְחִסְדָּא וְרַחֲמֵי, מִן קֳדָם אֱלָהָא מָארֵי שְׁמַיָּא וְאַרְעָא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא, חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה וְשֵיזָבָא וּרְפוּאָה וּגְאֻלָּה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה, לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"instruction","text":"לפני התפילה","cond":[]},{"kind":"text","text":"לְשֵׁם יִחוּד קֻדְשָׁא בְרִיךְ הוּא וּשְׁכִינְתֵּהּ, בִּדְחִילוּ וּרְחִימוּ וּרְחִימוּ וּדְחִילוּ, לְיַחֲדָא שֵׁם אוֹת י' וְאוֹת ה' בְּשֵׁם אוֹת ו' וְאוֹת ה' בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל יִשְׂרָאֵל, לַאֲקָמָא שְׁכִינְתָּא מִעַפְרָא וּלְעִלּוּי שְׁכִינַת עֻזֵּנוּ, הִנֵּה אֲנַחְנוּ בָּאִים לְהִתְפַּלֵּל תְּפִלַּת מִנְחָה שֶׁתִּקֵּן יִצְחָק אָבִינוּ עָלָיו הַשָּׁלוֹם, עִם כָּל הַמִּצְוׂת הַכְּלוּלוֹת בָּהּ, לְתַקֵּן אֶת שָׁרְשָׁהּ בְּמָקוֹם עֶלְיוֹן, לַעֲשׂוֹת נַחַת רוּחַ לְיוֹצְרֵנוּ, וְלַעֲשׂוֹת רְצוֹן בּוֹרְאֵנוּ. וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ:\n\nלַמְנַצֵּחַ עַל הַגִּתִּית, לִבְנֵי קֹרַח מִזְמוֹר: מַה יְּדִידוֹת מִשְׁכְּנוֹתֶיךָ יהוה צְבָאוֹת: נִכְסְפָה וְגַם כָּלְתָה נַפְשִׁי לְחַצְרוֹת יהוה, לִבִּי וּבְשָׂרִי, יְרַנְּנוּ אֶל אֵל חָי: גַּם צִפּור מָצְאָה בַּיִת וּדְרוֹר קֵן לָהּ אֲשֶׁר שָׁתָה אֶפְרֹחֶיהָ, אֶת מִזְבְּחוֹתֶיךָ יהוה צְבָאוֹת, מַלְכִּי וֵאלֹהָי: אַשְׁרֵי יוֹשְׁבֵי בֵיתֶךָ, עוֹד יְהַלְלוּךָ סֶּלָה: אַשְׁרֵי אָדָם עוֹז לוֹ בָךְ, מְסִלּוֹת בִּלְבָבָם: עֹבְרֵי בְּעֵמֶק הַבָּכָא מַעְיָן יְשִׁיתוּהוּ, גַּם בְּרָכוֹת יַעְטֶה מוֹרֶה: יֵלְכוּ מֵחַיִל אֶל חָיִל, יֵרָאֶה אֶל אֱלהִים בְּצִיּוֹן: יהוה אֱלהִים צְבָאוֹת שִׁמְעָה תְפִלָּתִי, הַאֲזִינָה אֱלהֵי יַעֲקֹב סֶלָה: מָגִנֵּנוּ רְאֵה אֱלֹהִים, וְהַבֵּט פְּנֵי מְשִׁיחֶךָ: כִּי טוֹב יוֹם בַּחֲצֵרֶיךָ מֵאָלֶף, בָּחַרְתִּי הִסְתּוֹפֵף בְּבֵית אֱלֹהַי, מִדּוּר בְּאָהֳלֵי רֶשַׁע: כִּי שֶׁמֶשׁ וּמָגֵן יהוה אֱלֹהִים, חֵן וְכָבוֹד יִתֵּן יהוה, לא יִמְנַע טוֹב לַהֹלְכִים בְּתָמִים: יהוה צְבָאוֹת, אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ:\n\nוַיְדַבֵּר יהוה אֶל מֹשֶׁה לֵּאמֹר: צַו אֶת בְּנֵי יִשרָאֵל וְאָמַרְתָּ אֲלֵהֶם, אֶת קָרְבָּנִי לַחְמִי לְאִשַּׁי, רֵיחַ נִיחֹחִי, תִּשְׁמְרוּ לְהַקְרִיב לִי בְּמוֹעֲדוֹ: וְאָמַרְתָּ לָהֶם, זֶה הָאִשֶּׁה אֲשֶׁר תַּקְרִיבוּ לַיהוה, כְּבָשִׂים בְּנֵי שָׁנָה תְמִימִים, שְׁנַיִם לַיּוֹם עֹלָה תָמִיד: אֶת הַכֶּבֶשׂ אֶחָד תַּעֲשֶׂה בַבֹּקֶר, וְאֵת הַכֶּבֶשׂ הַשֵּׁנִי תַּעֲשה בֵּין הָעַרְבָּיִם: וַעֲשִׂירִית הָאֵיפָה סֹלֶת לְמִנְחָה, בְּלוּלָה בְּשֶׁמֶן כָּתִית רְבִיעִת הַהִין: עֹלַת תָּמִיד, הָעֲשֻׂיָה בְּהַר סִינַי, לְרֵיחַ נִיחֹחַ אִשֶּׁה לַיהוה: וְנִסְכּוֹ רְבִיעִת הַהִין לַכֶּבֶשׂ הָאֶחָד, בַּקֹּדֶשׁ הַסֵּךְ נֶסֶךְ שֵׁכָר לַיהוה: וְאֵת הַכֶּבֶשׂ הַשֵּׁנִי תַּעֲשֶׂה בֵּין הָעַרְבָּיִם, כְּמִנְחַת הַבֹּקֶר וּכְנִסְכּוֹ תַּעֲשֶׂה, אִשֵּׁה רֵיחַ נִיחֹחַ לַיהוה:","cond":[]},{"kind":"header","text":"סדר הקטורת","cond":[]},{"kind":"instruction","text":"קטרת הסמים","cond":[]},{"kind":"text","text":"אַתָּה הוּא יהוה אֱלֹהֵינוּ שֶׁהִקְטִירוּ אֲבוֹתֵינוּ לְפָנֶיךָ אֶת קְטֹרֶת הַסַּמִּים בִּזְמַן שֶׁבֵּית הַמִּקְדָּשׁ קַיָּם, כַּאֲשֶׁר צִוִּיתָ אוֹתָם עַל יַד מֹשֶׁה נְבִיאָךְ כַּכָּתוּב בְּתוֹרָתָךְ: וַיֹּאמֶר יהוה אֶל מֹשֶׁה, קַח לְךָ סַמִּים נָטָף וּשְׁחֵלֶת וְחֶלְבְּנָה סַמִּים וּלְבֹנָה זַכָּה בַּד בְּבַד יִהְיֶה: וְעָשִׂיתָ אֹתָהּ קְטֹרֶת, רֹקַח מַעֲשֶׂה רוֹקֵחַ, מְמֻלָּח טָהוֹר קֹדֶשׁ: וְשָׁחַקְתָּ מִמֶּנָּה הָדֵק, וְנָתַתָּה מִמֶּנָּה לִפְנֵי הָעֵדֻת בְּאֹהֶל מוֹעֵד אֲשֶׁר אִוָּעֵד לְךָ שָׁמָּה, קֹדֶשׁ קָדָשִׁים תִּהְיֶה לָכֶם:\n\nוְנֶאֱמַר: וְהִקְטִיר עָלָיו אַהֲרֹן קְטֹרֶת סַמִּים, בַּבֹּקֶר בַּבֹּקֶר בְּהֵיטִיבוֹ אֶת הַנֵּרוֹת יַקְטִירֶנָּה: וּבְהַעֲלֹת אַהֲרֹן אֶת הַנֵּרֹת בֵּין הָעַרְבַּיִם יַקְטִירֶנָּה, קְטֹרֶת תָּמִיד לִפְנֵי יהוה לְדֹרֹתֵיכֶם:\n\nתָּנוּ רַבָּנָן: פִּטּוּם הַקְּטֹרֶת כֵּיצַד? שְׁלֹשׁ מֵאוֹת וְשִׁשִּׁים וּשְׁמוֹנָה מָנִים הָיוּ בָהּ. שְׁלֹשׁ מֵאוֹת וְשִׁשִּׁים וַחֲמִשָּׁה כְּמִנְיַן יְמוֹת הַחַמָּה, מָנֶה לְכָל יוֹם, מַחֲצִיתוֹ בַּבֹּקֶר וּמַחֲצִיתוֹ בָּעֶרֶב. וּשְׁלֹשָׁה מָנִים יְתֵרִים שֶׁמֵּהֶם מַכְנִיס כֹּהֵן גָּדוֹל וְנוֹטֵל מֵהֶם מְלֹא חָפְנָיו בְּיוֹם הַכִּפּוּרִים, וּמַחֲזִירָן לְמַכְתֶּשֶׁת בְּעֶרֶב יום הַכִּפּוּרִים כְּדֵי לְקַיֵּם מִצְוַת דַקָּה מִן הַדַּקָּה. וְאַחַד עָשר סַמָּנִים הָיוּ בָהּ, וְאֵלּוּ הֵן: (א) הַצֳּרִי (ב) וְהַצִּפֹּרֶן, (ג) וְהַחֶלְבְּנָה (ד) וְהַלְּבוֹנָה מִשְׁקַל שִׁבְעִים שִׁבְעִים מָנֶה, (ה) מֹר (ו) וּקְצִיעָה, (ז) וְשִׁבֹּלֶת נֵרְדְּ (ח) וְכַרְכֹּם מִשְׁקַל שִׁשָּׁה עָשָׂר שִׁשָּׁה עָשָׂר מָנֶה, (ט) קֹשְׁטְ שְׁנֵים עָשָׂר, (י) קִלּוּפָה שְׁלֹשָׁה, (יא) קִנָּמון תִּשְׁעָה, בֹּרִית כַּרְשִׁינָא תִּשְׁעָה קַבִּין, יֵין קַפְרִיסִין סְאִין תְּלָת וְקַבִּין תְּלָתָא, וְאִם לֹא מָצָא יֵין קַפְרִיסִין מֵבִיא חֲמַר חִיוָרְ עַתִּיק. מֶלַח סְדוֹמִית רֹבַע מַעֲלֶה עָשָׁן כָּל שֶׁהוּא. רִבִּי נָתָן הַבַּבְלִי אוֹמֵר: אַף כִּפַּת הַיַּרְדֵּן כָּל שֶׁהִיא. אִם נָתַן בָּהּ דְּבַשׁ פְּסָלָהּ, וְאִם חִסַּר אַחַת מִכָּל סַמָּנֶיהָ חַיָּב מִיתָה.\n\nרַבָּן שִׁמְעוֹן בֶּן גַּמְלִיאֵל אוֹמֵר: הַצֳּרִי אֵינוֹ אֶלָּא שְׂרָף הַנּוֹטֵף מֵעֲצֵי הַקְּטָף. בֹּרִית כַּרְשִׁינָה לְמָה הִיא בָאָה? כְּדֵי לְשַׁפּוֹת בָּהּ אֶת הַצִּפֹּרֶן כְּדֵי שֶׁתְּהֵא נָאָה. יֵין קַפְרִיסִין לְמָה הוּא בָא? כְּדֵי לִשְׁרוֹת בּוֹ אֶת הַצִּפֹּרֶן כְּדֵי שֶׁתְּהֵא עַזָּה. וַהֲלֹא מֵי רַגְלַיִם יָפִין לָהּ, אֶלָּא שֶׁאֵין מַכְנִיסִין מֵי רַגְלַיִם בַּמִּקְדָּשׁ מִפְּנֵי הַכָּבוֹד.\n\nתַּנְיָא: רִבִּי נָתָן אוֹמֵר: כְּשֶׁהוּא שׁוֹחֵק אוֹמֵר: \"הָדֵק הֵיטֵב, הֵיטֵב הָדֵק\", מִפְּנֵי שֶׁהַקּוֹל יָפֶה לַבְּשָׂמִים. פִּטְּמָהּ לַחֲצָאִין כְּשֵׁרָה. לִשְׁלִישׁ וְלִרְבִיעַ לֹא שָׁמַעְנוּ. אָמַר רִבִּי יְהוּדָה: זֶה הַכְּלָל: אִם כְּמִדָּתָהּ כְּשֵׁרָה לַחֲצָאִין, וְאִם חִסֵּר אַחַת מִכָּל סַמְּמָנֶיהָ חַיָּב מִיתָה.\n\nתָּנֵי בַר קַפָּרָא: אַחַת לְשִׁשִּׁים או לְשִׁבְעִים שָׁנָה הָיְתָה בָאָה שֶׁל שִׁירַיִם לַחֲצָאִין. וְעוֹד תָּנֵי בַּר קַפָּרָא: אִלּוּ הָיָה נוֹתֵן בָּהּ קָרְטוֹב שֶׁל דְּבַשׁ אֵין אָדָם יָכוֹל לַעֲמֹד מִפְּנֵי רֵיחָהּ, וְלָמָּה אֵין מְעָרְבִין בָּהּ דְּבַשׁ? מִפְּנֵי שֶׁהַתּוֹרָה אָמְרָה: כִּי כָל שְׂאֹר וְכָל דְּבַשׁ לֹא תַקְטִירוּ מִמֶּנּוּ אִשֶּׁה לַיהוה:\n\nיהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה:\nיהוה צְבָאוֹת, אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ:\nיהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:\n\nוְעָרְבָה לַיהוה מִנְחַת יְהוּדָה וִירוּשָׁלָיִם כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמוֹנִיּות:","cond":[]},{"kind":"header","text":"אשרי","cond":[]},{"kind":"text","text":"אַשְׁרֵי יוֹשְׁבֵי בֵיתֶךָ עוֹד יְהַלְלוּךָ סֶּלָה:\nאַשְׁרֵי הָעָם שֶׁכָּכָה לּוֹ אַשְׁרֵי הָעָם שֶׁיהוה אֱלֹהָיו:\nתְּהִלָּה לְדָוִד, אֲרוֹמִמְךָ אֱלוֹהַי הַמֶּלֶךְ וַאֲבָרְכָה שִׁמְךָ לְעוֹלָם וָעֶד:\nבְּכָל יוֹם אֲבָרְכֶךָּ וַאֲהַלְלָה שִׁמְךָ לְעוֹלָם וָעֶד:\nגָּדוֹל יהוה וּמְהֻלָּל מְאֹד וְלִגְדֻלָּתוֹ אֵין חֵקֶר:\nדּוֹר לְדוֹר יְשַׁבַּח מַעֲשֶׂיךָ וּגְבוּרֹתֶיךָ יַגִּידוּ:\nהֲדַר כְּבוֹד הוֹדֶךָ וְדִבְרֵי נִפְלְאוֹתֶיךָ אָשִׂיחָה:\nוֶעֱזוּז נוֹרְאֹתֶיךָ יֹאמֵרוּ וּגְדוּלָּתְךָ אֲסַפְּרֶנָּה:\nזֵכֶר רַב טוּבְךָ יַבִּיעוּ וְצִדְקָתְךָ יְרַנֵּנוּ:","cond":[]},{"kind":"text","text":"חַנּוּן וְרַחוּם יהוה אֶרֶךְ אַפַּיִם וּגְדָל חָסֶד:\nטוֹב יהוה לַכֹּל וְרַחֲמָיו עַל כָּל מַעֲשָׂיו:\nיוֹדוּךָ יהוה כָּל מַעֲשֶׂיךָ וַחֲסִידֶיךָ יְבָרְכוּכָה:\nכְּבוֹד מַלְכוּתְךָ יֹאמֵרוּ וּגְבוּרָתְךָ יְדַבֵּרוּ:\nלְהוֹדִיעַ לִבְנֵי הָאָדָם גְּבוּרֹתָיו וּכְבוֹד הֲדַר מַלְכוּתוֹ:\nמַלְכוּתְךָ מַלְכוּת כָּל עֹלָמִים וּמֶמְשַׁלְתְּךָ בְּכָל דּוֹר וָדוֹר:\nסוֹמֵךְ יהוה לְכָל הַנֹּפְלִים וְזוֹקֵף לְכָל הַכְּפוּפִים:\nעֵינֵי כֹל אֵלֶיךָ יְשַׂבֵּרוּ וְאַתָּה נוֹתֵן לָהֶם אֶת אָכְלָם בְּעִתּוֹ:","cond":[]},{"kind":"text","text":"פּוֹתֵחַ אֶת יָדֶךָ וּמַשְׂבִּיעַ לְכָל חַי רָצוֹן:\nצַדִּיק יהוה בְּכָל דְּרָכָיו וְחָסִיד בְּכָל מַעֲשָׂיו:\nקָרוֹב יהוה לְכָל קֹרְאָיו לְכֹל אֲשֶׁר יִקְרָאֻהוּ בֶאֱמֶת:\nרְצוֹן יְרֵאָיו יַעֲשֶׂה וְאֶת שַׁוְעָתָם יִשְׁמַע וְיוֹשִׁיעֵם:\nשׁוֹמֵר יהוה אֶת כָּל אֹהֲבָיו וְאֵת כָּל הָרְשָׁעִים יַשְׁמִיד:\nתְּהִלַּת יהוה יְדַבֶּר פִּי וִיבָרֵךְ כָּל בָּשָׂר שֵׁם קָדְשׁוֹ לְעוֹלָם וָעֶד:\nוַאֲנַחְנוּ נְבָרֵךְ יָהּ מֵעַתָּה וְעַד עוֹלָם הַלְלוּיָהּ:","cond":[]},{"kind":"instruction","text":"חצי קדיש","cond":["taanit"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["taanit"]},{"kind":"header","text":"הוצאת ספר תורה","cond":["taanit"]},{"kind":"instruction","text":"הוצאת ספר תורה","cond":["taanit"]},{"kind":"text","text":"גַּדְּלוּ לַיהוה אִתִּי, וּנְרוֹמְמָה שְׁמוֹ יַחְדָּו: רוֹמְמוּ יהוה אֱלֹהֵינוּ, וְהִשְׁתַּחֲווּ לַהֲדֹם רַגְלָיו, קָדוֹשׁ הוּא: רוֹמְמוּ יהוה אֱלֹהֵינוּ וְהִשְׁתַּחֲווּ לְהַר קָדְשׁוֹ, כִּי קָדוֹשׁ יהוה אֱלֹהֵינוּ: אֵין קָדוֹשׁ כַּיהוה כִּי אֵין בִּלְתֶּךָ. וְאֵין צוּר כֵּאלֹהֵינוּ: כִּי מִי אֱלוֹהַּ מִבַּלְעֲדֵי יהוה, וּמִי צוּר זוּלָתִי אֱלֹהֵינוּ: תּוֹרָה צִוָּה לָנוּ מֹשֶׁה, מוֹרָשָׁה קְהִלַּת יַעֲקֹב: עֵץ חַיִּים הִיא לַמַּחֲזִיקִים בָּהּ, וְתוֹמְכֶיהָ מְאֻשָּׁר: דְּרָכֶיהָ דַרְכֵי נֹעַם וְכָל נְתִיבוֹתֶיהָ שָׁלוֹם: שָׁלוֹם רָב לְאוֹהֲבֵי תוֹרָתֶךָ וְאֵין לָמו מִכְשׁוֹל: יהוה עֹז לְעַמּוֹ יִתֵּן, יהוה יְבָרֵךְ אֶת עַמּוֹ בַשָּׁלוֹם: כִּי שֵׁם יהוה אֶקְרָא, הָבוּ גֹדֶל לֵאלֹהֵינוּ: הַכֹּל תְּנוּ עֹז לֵאלֹהִים וּתְנוּ כָבוֹד לַתּוֹרָה.","cond":["taanit"]},{"kind":"instruction","text":"ומגביה ספר תורה ומראה הכתב לקהל ואומרים:","cond":["taanit"]},{"kind":"text","text":"וְזֹאת הַתּוֹרָה אֲשֶׁר שָׂם מֹשֶׁה לִפְנֵי בְּנֵי יִשְׂרָאֵל: תּוֹרָה צִוָּה לָנוּ מֹשֶׁה, מוֹרָשָׁה קְהִלַּת יַעֲקֹב: הָאֵל, תָּמִים דַּרְכּוֹ, אִמְרַת יהוה צְרוּפָה, מָגֵן הוּא לְכָל הַחֹסִים בּוֹ:","cond":["taanit"]},{"kind":"instruction","text":"קריאת התורה","cond":["taanit"]},{"kind":"instruction","text":"לפני הקריאה מברך העולה:","cond":["taanit"]},{"kind":"instruction","text":"חזן:","cond":["taanit"]},{"kind":"text","text":"בָּרְכוּ אֶת יהוה הַמְבֹרָךְ.","cond":["taanit"]},{"kind":"instruction","text":"קהל וחזן:","cond":["taanit"]},{"kind":"text","text":"בָּרוּךְ יהוה הַמְבֹרָךְ לְעוֹלָם וָעֶד.","cond":["taanit"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר בָּחַר בָּנוּ מִכָּל הָעַמִּים וְנָתַן לָנוּ אֶת תּוֹרָתוֹ. בָּרוּךְ אַתָּה יהוה, נוֹתֵן הַתּוֹרָה.","cond":["taanit"]},{"kind":"instruction","text":"לאחר הקריאה מברך העולה:","cond":["taanit"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר נָתַן לָנוּ אֶת תּוֹרָתוֹ תּוֹרַת אֱמֶת, וְחַיֵּי עוֹלָם נָטַע בְּתוֹכֵנוּ. בָּרוּךְ אַתָּה יהוה, נוֹתֵן הַתּוֹרָה.","cond":["taanit"]},{"kind":"header","text":"קריאת התורה","cond":["taanit"]},{"kind":"text","text":"וַיְחַל מֹשֶׁה אֶת פְּנֵי יהוה אֱלֹהָיו, וַיֹּאמֶר לָמָה יהוה יֶחֱרֶה אַפְּךָ בְּעַמֶּךָ אֲשֶׁר הוֹצֵאתָ מֵאֶרֶץ מִצְרַיִם בְּכֹחַ גָּדוֹל וּבְיָד חֲזָקָה: לָמָּה יֹאמְרוּ מִצְרַיִם לֵאמֹר בְּרָעָה הוֹצִיאָם לַהֲרֹג אֹתָם בֶּהָרִים וּלְכַלֹּתָם מֵעַל פְּנֵי הָאֲדָמָה, שׁוּב מֵחֲרוֹן אַפֶּךָ וְהִנָּחֵם עַל הָרָעָה לְעַמֶּךָ: זְכֹר לְאַבְרָהָם לְיִצְחָק וּלְיִשְׂרָאֵל עֲבָדֶיךָ אֲשֶׁר נִשְׁבַּעְתָּ לָהֶם בָּךְ, וַתְּדַבֵּר אֲלֵהֶם אַרְבֶּה אֶת זַרְעֲכֶם כְּכוֹכְבֵי הַשָּׁמָיִם, וְכָל הָאָרֶץ הַזֹּאת אֲשֶׁר אָמַרְתִּי אֶתֵּן לְזַרְעֲכֶם וְנָחֲלוּ לְעֹלָם: וַיִּנָּחֶם יהוה, עַל הָרָעָה אֲשֶׁר דִּבֶּר לַעֲשׂוֹת לְעַמּוֹ:","cond":["taanit"]},{"kind":"instruction","text":"עד כאן לכהן","cond":["taanit"]},{"kind":"text","text":"וַיֹּאמֶר יהוה אֶל מֹשֶׁה פְּסָל לְךָ שְׁנֵי לֻחֹת אֲבָנִים כָּרִאשֹׁנִים, וְכָתַבְתִּי עַל הַלֻּחֹת אֶת הַדְּבָרִים אֲשֶׁר הָיוּ עַל הַלֻּחֹת הָרִאשֹׁנִים אֲשֶׁר שִׁבַּרְתָּ: וֶהְיֵה נָכוֹן לַבֹּקֶר, וְעָלִיתָ בַבֹּקֶר אֶל הַר סִינַי וְנִצַּבְתָּ לִי שָׁם עַל רֹאשׁ הָהָר: וְאִישׁ לֹא יַעֲלֶה עִמָּךְ וְגַם אִישׁ אַל יֵרָא בְּכָל הָהָר, גַּם הַצֹּאן וְהַבָּקָר אַל יִרְעוּ אֶל מוּל הָהָר הַהוּא:","cond":["taanit"]},{"kind":"instruction","text":"עד כאן ללוי","cond":["taanit"]},{"kind":"text","text":"וַיִּפְסֹל שְׁנֵי לֻחֹת אֲבָנִים כָּרִאשֹׁנִים, וַיַּשְׁכֵּם מֹשֶׁה בַבֹּקֶר וַיַּעַל אֶל הַר סִינַי כַּאֲשֶׁר צִוָּה יהוה אֹתוֹ, וַיִּקַּח בְּיָדוֹ שְׁנֵי לֻחֹת אֲבָנִים: וַיֵּרֶד יהוה בֶּעָנָן וַיִּתְיַצֵּב עִמּוֹ שָׁם, וַיִּקְרָא בְשֵׁם, יהוה: וַיַּעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא, יהוה, יהוה, אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב חֶסֶד וֶאֱמֶת: נֹצֵר חֶסֶד לָאֲלָפִים, נֹשֵׂא עָוׂן וָפֶשַׁע וְחַטָּאָה, וְנַקֵּה לֹא יְנַקֶּה, פֹּקֵד עֲוׂן אָבוֹת עַל בָּנִים וְעַל בְּנֵי בָנִים, עַל שִׁלֵּשִׁים וְעַל רִבֵּעִים: וַיְמַהֵר מֹשֶׁה, וַיִּקֹּד אַרְצָה וַיִּשְׁתָּחוּ: וַיֹּאמֶר אִם נָא מָצָאתִי חֵן בְּעֵינֶיךָ אֲדֹנָי יֵלֶךְ נָא אֲדֹנָי בְּקִרְבֵּנוּ, כִּי עַם קְשֵׁה עֹרֶף הוּא, וְסָלַחְתָּ לַעֲוׂנֵנוּ וּלְחַטָּאתֵנוּ וּנְחַלְתָּנוּ: וַיֹּאמֶר הִנֵּה אָנֹכִי כֹּרֵת בְּרִית, נֶגֶד כָּל עַמְּךָ אֶעֱשֶׂה נִפְלָאֹת אֲשֶׁר לֹא נִבְרְאוּ בְכָל הָאָרֶץ וּבְכָל הַגּוֹיִם, וְרָאָה כָל הָעָם אֲשֶׁר אַתָּה בְקִרְבּוֹ אֶת מַעֲשֵׂה יהוה כִּי נוֹרָא הוּא, אֲשֶׁר אֲנִי עֹשֶׂה עִמָּךְ:","cond":["taanit"]},{"kind":"instruction","text":"עד כאן לישראל","cond":["taanit"]},{"kind":"header","text":"הכנסת ספר תורה","cond":["taanit"]},{"kind":"instruction","text":"הכנסת ספר תורה","cond":["taanit"]},{"kind":"text","text":"יְהַלְלוּ אֶת שֵׁם יהוה כִּי נִשְׂגָּב שְׁמוֹ לְבַדּוֹ, הוֹדוֹ עַל אֶרֶץ וְשָׁמָיִם: וַיָּרֶם קֶרֶן לְעַמּוֹ, תְּהִלָּה לְכָל חֲסִידָיו, לִבְנֵי יִשְׂרָאֵל עַם קְרֹבוֹ, הַלְלוּיָהּ: יהוה הוּא הָאֱלֹהִים. יהוה הוּא הָאֱלֹהִים בַּשָּׁמַיִם מִמַּעַל וְעַל הָאָרֶץ מִתָּחַת, אֵין עוֹד: אֵין כָּמוֹךָ בָאֱלֹהִים, אֲדֹנָי, וְאֵין כְּמַעֲשֶׂיךָ: הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם:","cond":["taanit"]},{"kind":"text","text":"תִּכּוֹן תְּפִלָּתִי קְטֹרֶת לְפָנֶיךָ, מַשְׂאַת כַּפַּי מִנְחַת עָרֶב: הַקְשִׁיבָה לְקוֹל שַׁוְעִי מַלְכִּי וֵאלֹהָי, כִּי אֵלֶיךָ אֶתְפַּלָּל:","cond":[]},{"kind":"instruction","text":"חצי קדיש","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"header","text":"עמידה","cond":[]},{"kind":"instruction","text":"תפילת העמידה","cond":[]},{"kind":"text","text":"אֲדֹנָי, שְׂפָתַי תִּפְתָּח, וּפִי יַגִּיד תְּהִלָּתֶךָ:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יְהֹוָה, אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק וֵאלֹהֵי יַעֲקֹב, הָאֵל הַגָּדוֹל, הַגִּבּוֹר וְהַנּוֹרָא, אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, קוֹנֵה הַכֹּל וְזוֹכֵר חַסְדֵי אָבוֹת וּמֵבִיא גּוֹאֵל לִבְנֵי בְנֵיהֶם לְמַעַן שְׁמוֹ בְּאַהֲבָה.","cond":[]},{"kind":"special","text":"זָכְרֵנוּ לְחַיִּים, מֶלֶךְ חָפֵץ בַּחַיִּים, כָּתְבֵנוּ בְּסֵפֶר חַיִּים, לְמַעַנְךָ אֱלֹהִים חַיִּים.","cond":["ayt"]},{"kind":"text","text":"מֶלֶךְ עוֹזֵר וּמוֹשִׁיעַ וּמָגֵן. בָּרוּךְ אַתָּה יַהַוַהַ, מָגֵן אַבְרָהָם.","cond":[]},{"kind":"text","text":"אַתָּה גִּבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֵּה מֵתִים אַתָּה, רַב לְהוֹשִׁיעַ,","cond":[]},{"kind":"summer","text":"מוֹרִיד הַטָּל,","cond":["summerTal"]},{"kind":"winter","text":"מַשִּׁיב הָרוּחַ וּמוֹרִיד הַגֶּשֶׁם,","cond":["winterTal"]},{"kind":"text","text":"מְכַלְכֵּל חַיִּים בְּחֶסֶד, מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים, סוֹמֵךְ נוֹפְלִים וְרוֹפֵא חוֹלִים, וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמוּנָתוֹ לִישֵׁנֵי עָפָר. מי כָמוֹךָ בַּעַל גְּבוּרוֹת וּמִי דוֹמֶה לָךְ, מֶלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִיחַ יְשׁוּעָה.","cond":[]},{"kind":"special","text":"מִי כָמוֹךָ אַב הָרַחֲמָן, זוֹכֵר יְצוּרָיו בְּרַחֲמִים לְחַיִּים.","cond":["ayt"]},{"kind":"text","text":"וְנֶאֱמָן אַתָּה לְהַחֲיוֹת מֵתִים. בָּרוּךְ אַתָּה יֵהֵוֵהֵ, מְחַיֵּה הַמֵּתִים.","cond":[]},{"kind":"text","text":"אַתָּה קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ, וּקְדוֹשִׁים בְּכָל-יוֹם יְהַלְלוּךָ סֶּלָה.","cond":[]},{"kind":"special","text":"בָּרוּךְ אַתָּה יֹהֵוָה, הַמֶּלֶךְ הַקָּדוֹשׁ.","cond":["ayt"]},{"kind":"text","text":"בּרוּךְ אַתָּה יֹהֵוָה, הָאֵל הַקָּדוֹשׁ.","cond":["noayt"]},{"kind":"text","text":"אַתָּה חוֹנֵן לְאָדָם דַּעַת וּמְלַמֵּד לֶאֱנוֹשׁ בִּינָה. וְחָנֵּנוּ מֵאִתְּךָ חָכְמָה בִּינָה וָדָעַת. בָּרוּךְ אַתָּה יַהַוַהַ חוֹנֵן הַדָּעַת.","cond":[]},{"kind":"text","text":"הֲשִׁיבֵנוּ אָבִינוּ לְתוֹרָתֶךָ, וְקָרְבֵנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶךָ, וְהַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ. בָּרוּךְ אַתָּה יֵהֵוֵהֵ, הָרוֹצֶה בִּתְשׁוּבָה.","cond":[]},{"kind":"text","text":"סְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחֹל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ, כִּי אֵל טוֹב וְסַלָּח אָתָּה. בָּרוּךְ אַתָּה יֶהֶוֶהֶ, חַנּוּן הַמַּרְבֶּה לִסְלֹחַ.","cond":[]},{"kind":"text","text":"רְאֵה נָא בְעָנְיֵנוּ וְרִיבָה רִיבֵנוּ, וּמַהֵר לְגָאֳלֵנוּ גְאֻלָּה שְׁלֵמָה לְמַעַן שְׁמֶךָ, כִּי אֵל גּוֹאֵל חָזָק אָתָּה. בָּרוּךְ אַתָּה יְהְוְהְ, גוֹאֵל יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"רְפָאֵנוּ יְהֹוָה וְנֵרָפֵא, הוֹשִׁיעֵנוּ וְנִוָּשֵׁעָה כִּי תְהִלָּתֵנוּ אָתָּה, וְהַעֲלֵה אֲרוּכָה וּמַרְפֵּא לְכָל-תַּחֲלוּאֵינוּ וּלְכָל-מַכְאוֹבֵינוּ וּלְכָל-מַכּוֹתֵינוּ.","cond":[]},{"kind":"special","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁתִּשְׁלַח מְהֵרָה רְפוּאָה שְׁלֵמָה מִן הַשָּׁמַיִם, רְפוּאַת הַנֶּפֶשׁ וּרְפוּאַת הַגּוּף לַחוֹלֶה (לנקבה: לַחוֹלָה, לרבים: לַחוֹלִים, לרבות: לַחוֹלוֹת):\n:=:=\nבְּתוֹךְ שְׁאָר חוֹלֵי יִשְׂרָאֵל.","cond":["doctor"]},{"kind":"text","text":"כִּי אֵל רוֹפֵא רַחֲמָן וְנֶאֱמָן אָתָּה. בָּרוּךְ אַתָּה יֹהֹוׂהֹ, רוֹפֵא חוֹלֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"summer","text":"בָּרְכֵנוּ יְהֹוָה אֱלֹהֵינוּ בְּכָל מַעֲשֵׂי יָדֵינוּ, וּבָרֵךְ שְׁנָתֵנוּ בְּטַלְלֵי רָצוֹן בְּרָכָה וּנְדָבָה, וּתְהִי אַחֲרִיתָהּ חַיִּים וְשָׂבָע וְשָׁלוֹם כַּשָּׁנִים הַטּוֹבוֹת לִבְרָכָה. כִּי אֵל טוֹב וּמֵטִיב אַתָּה וּמְבָרֵךְ הַשָּׁנִים. בָּרוּךְ אַתָּה יִהִוִהִ, מְבָרֵךְ הַשָּׁנִים.","cond":["summerBracha"]},{"kind":"winter","text":"בָּרֵךְ עָלֵינוּ יְהֹוָה אֱלֹהֵינוּ אֶת הַשָּׁנָה הַזֹּאת וְאֶת כָּל מִינֵי תְּבוּאָתָהּ לְטוֹבָה, וְתֵן טַל וּמָטָר לִבְרָכָה עַל כָּל פְּנֵי הָאֲדָמָה, וְרַוֵּה פְּנֵי תֵבֵל וְשַׂבַּע אֶת הָעוֹלָם כֻּלּוֹ מִטּוּבָךְ, וּמַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ וּמֵעֹשֶׁר מַתְּנוֹת יָדֶיךָ. שָׁמְרָה וְהַצִּילָה שָׁנָה זוֹ מִכָּל דָּבָר רָע וּמִכָּל מִינֵי מַשְׁחִית וּמִכָּל מִינֵי פֻרְעָנוּת, וַעֲשֵׂה לָהּ תִּקְוָה טוֹבה וְאַחֲרִית שָׁלוֹם. חוּס וְרַחֵם עָלֶיהָ וְעַל כָּל תְּבוּאָתָהּ וּפֵירוֹתֶיהָ, וּבָרְכָהּ בְּגִשְׁמֵי רָצוֹן בְּרָכָה וּנְדָבָה, וּתְהִי אַחֲרִיתָהּ חַיִּים וְשָׂבָע וְשָׁלוֹם כַּשָּׁנִים הַטּוֹבוֹת לִבְרָכָה. כִּי אֵל טוֹב וּמֵטִיב אַתָּה וּמְבָרֵךְ הַשָּׁנִים. בָּרוּךְ אַתָּה יִהִוִהִ, מְבָרֵךְ הַשָּׁנִים.","cond":["winterBracha"]},{"kind":"text","text":"תְּקַע בְּשׁוֹפָר גָּדוֹל לְחֵרוּתֵנוּ, וְשָׂא נֵס לְקַבֵּץ גָּלֻיּוֹתֵינוּ, וְקַבְּצֵנוּ יַחַד מֵאַרְבַּע כַּנפוֹת הָאָרֶץ לְאַרְצֵנוּ. בָּרוּךְ אַתָּה יֻהֻוֻהֻ, מְקַבֵּץ נִדְחֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"הָשִׁיבָה שׁוֹפְטֵינוּ כְּבָרִאשׁוֹנָה, וְיוֹעֲצֵינוּ כְּבַתְּחִלָּה, וְהָסֵר מִמֶּנוּ יָגוֹן וַאֲנָחָה, וּמְלֹךְ עָלֵינוּ מְהֵרָה אַתָּה יְהֹוָה לְבַדְּךָ, בְּחֶסֶד וּבְרַחֲמִים, בְּצֶדֶק וּבְמִשְׁפָּט.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יוּהוּווּהוּ, מֶלֶךְ אוֹהֵב צְדָקָה וּמִשְׁפָּט.","cond":["noAyt"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יוּהוּווּהוּ, הַמֶּלֶךְ הַמִּשְׁפָּט.","cond":["ayt"]},{"kind":"text","text":"לַמִּינִים וְלַמַּלְשִׁינִים אַל תְּהִי תִקְוָה, וְכָל הַזֵּדִים כְּרֶגַע יֹאבֵדוּ, וְכָל אוֹיְבֶיךָ וְכָל שׂוֹנְאֶיךָ מְהֵרָה יִכָּרֵתוּ, וּמַלְכוּת הָרִשְׁעָה מְהֵרָה תְעַקֵּר וּתְשַׁבֵּר וּתְכַלֵּם וְתַכְנִיעֵם בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יָהָוָהָ, שׁוֹבֵר אוֹיְבִים וּמַכְנִיעַ זֵדִים.","cond":[]},{"kind":"text","text":"עַל הַצַּדִּיקִים וְעַל הַחֲסִידִים וְעַל שְׁאֵרִית עַמְּךָ בֵּית יִשְׂרָאֵל וְעַל זִקְנֵיהֶם וְעַל פְּלֵטַת בֵּית סוֹפְרֵיהֶם וְעַל גֵּרֵי הַצֶּדֶק וְעָלֵינוּ, יֶהֱמוּ נָא רַחֲמֶיךָ יְהֹוָה אֱלֹהֵינוּ, וְתֵן שָׂכָר טוֹב לְכָל הַבּוֹטְחִים בְּשִׁמְךָ בֶאֱמֶת, וְשִׂים חֶלְקֵנוּ עִמָּהֶם, וּלְעוֹלָם לֹא נֵבוֹשׁ כִּי בְךָ בָטַחְנוּ, וְעַל חַסְדְּךָ הַגָּדוֹל בֶּאֱמֶת נִשְׁעָנְנוּ. בָּרוּךְ אַתָּה יוּהוּווּהוּ, מִשְׁעָן וּמִבְטָח לַצַּדִּיקִים.","cond":[]},{"kind":"text","text":"תִּשְׁכּוֹן בְּתוֹךְ יְרוּשָׁלַיִם עִירְךָ כַּאֲשֶׁר דִּבַּרְתָּ, וְכִסֵּא דָוִד עַבְדְּךָ מְהֵרָה בְתוֹכָהּ תָּכִין, וּבְנֵה אוֹתָהּ בִּנְיַן עוֹלָם בִּמְהֵרָה בְיָמֵינוּ.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יֻהֻוֻהֻ, בּוֹנֵה יְרוּשָׁלָיִם.","cond":["noTishaaBeav"]},{"kind":"special","text":"נַחֵם יהוה אֱלֹהֵינוּ אֶת אֲבֵלֵי צִיּוֹן וְאֶת אֲבֵלֵי יְרוּשָׁלַיִם, וְאֶת הָעִיר הַחֲרֵבָה וְהַבְּזוּיָה וְהַשוֹמֵמָה, מִבְּלִי בָנֶיהָ הִיא יוֹשֶׁבֶת, וְרֹאשָׁהּ חָפוּי כְּאִשָּׁה עֲקָרָה שֶׁלֹּא יָלָדָה. וַיְבַלְּעוּהָ לִגְיוֹנִים וַיִּירָשׁוּהָ, וַיַטִּילוּ אֶת עַמְּךָ יִשְׂרָאֵל לַחֶרֶב, וַיַּהַרְגוּ בְזָדוֹן חֲסִידָי עֶלְיוֹן. עַל כֵּן צִיּוֹן בְּמֶרֶר תִּבְכֶּה וִירוּשָׁלַיִם תִּתֵּן קוֹלָהּ. לִבִּי לִבִּי עַל חַלְלֵיהֶם, מֵעַי מֵעַי עַל הֲרוּגֵיהֶם. כִּי אַתָּה יהוה בָּאֵשׁ הִצַּתָּהּ, וּבָאֵשׁ אַתָּה עָתִיד לִבְנוֹתָהּ, כַּכָּתוּב: וַאֲנִי אֶהְיֶה לָהּ נְאֻם יְהוה חוֹמַת אֵשׁ סָבִיב, וּלְכָבוֹד אֶהְיֶה בְתוֹכָהּ: בָּרוּךְ אַתָּה יהוה, מְנַחֵם צִיּוֹן בְּבִנְיַן יְרוּשָׁלַיִם.","cond":["tishaaBeav"]},{"kind":"text","text":"אֶת צֶמַח דָּוִד עַבְדְּךָ מְהֵרָה תַצְמִיחַ, וְקַרְנוֹ תָרוּם בִּישׁוּעָתֶךָ. כִּי לִישׁוּעָתְךָ קִוִּינוּ וְצִפִּינוּ כָּל הַיּוֹם. בָּרוּךְ אַתָּה יִהִוִהִ, מַצְמִיחַ קֶרֶן יְשׁוּעָה.","cond":[]},{"kind":"text","text":"שְׁמַע קוֹלֵנוּ יְהֹוָה אֱלֹהֵינוּ, אָב הָרַחֲמָן רַחֵם עָלֵינוּ, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ, כִּי אֵל שׁוֹמֵעַ תְּפִלּוֹת וְתַחֲנוּנִים אָתָּה, וּמִלְּפָנֶיךָ מַלְכֵּנוּ, רֵיקָם אַל תְּשִׁיבֵנוּ. חָנֵּנוּ וַעֲנֵנוּ וּשְׁמַע תְּפִלָּתֵנוּ.","cond":[]},{"kind":"instruction","text":"בתענית ציבור יאמר היחיד \"עננו\".","cond":["taanit"]},{"kind":"special","text":"עֲנֵנוּ אָבִינוּ עֲנֵנוּ בְּיוֹם צוֹם הַתַּעֲנִית הַזֶּה, כִּי בְצָרָה גְדוֹלָה אֲנָחְנוּ. אַל תֵּפֶן לְרִשְׁעֵנוּ, וְאַל תִּתְעַלַּם מַלְכֵּנוּ מִבַּקָּשָׁתֵנוּ, הֱיֵה נָא קָרוֹב לְשַׁוְעָתֵנוּ. טֶרֶם נִקְרָא אֵלֶיךָ אַתָּה תַעֲנֶה, נְדַבֵּר וְאַתָּה תִשְׁמַע, כַּדָּבָר שֶׁנֶּאֱמַר: וְהָיָה טֶרֶם יִקְרָאוּ וַאֲנִי אֶעֱנֶה, עוֹד הֵם מְדַבְּרִים וַאֲנִי אֶשְׁמָע: כִּי אַתָּה יהוה פּוֹדֶה וּמַצִּיל וְעוֹנֶה וּמְרַחֵם בְּכָל עֵת צָרָה וְצוּקָה.","cond":["taanit"]},{"kind":"text","text":"כִּי אַתָּה שׁוֹמֵעַ תְּפִלַּת כָּל פֶּה. בָּרוּךְ אַתָּה יהוה, שׁוֹמֵעַ תְּפִלָּה.","cond":[]},{"kind":"text","text":"רְצֵה יְהֹוָה אֱלֹהֵינוּ בְּעַמְּךָ יִשְׂרָאֵל, וּלִתְפִלָּתָם שְׁעֵה, וְהָשֵׁב הָעֲבוֹדָה לִדְבִיר בֵּיתֶךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם מְהֵרָה בְאַהֲבָה תְּקַבֵּל בְּרָצוֹן, וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּךָ.","cond":[]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, זִכְרוֹן יְרוּשָׁלַיִם עִירָךְ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן לְחֶסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["rh"]},{"kind":"special","text":"רֹאשׁ הַחֹדֶשׁ הַזֶּה,","cond":["rh"]},{"kind":"special","text":"לְרַחֵם בּוֹ עָלֵינוּ וּלְהוֹשִׁיעֵנוּ. זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. בִּדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וַחֲמוֹל וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["rh"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, זִכְרוֹן יְרוּשָׁלַיִם עִירָךְ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן לְחֶסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["sucot"]},{"kind":"special","text":"חַג הַסֻּכּוֹת הַזֶּה, בְּיוֹם מִקְרָא קֹדֶשׁ הַזֶּה,","cond":["sucot"]},{"kind":"special","text":"לְרַחֵם בּוֹ עָלֵינוּ וּלְהוֹשִׁיעֵנוּ. זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. בִּדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וַחֲמוֹל וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["sucot"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, זִכְרוֹן יְרוּשָׁלַיִם עִירָךְ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן לְחֶסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["pesach"]},{"kind":"special","text":"חַג הַמַּצּוֹת הַזֶּה, בְּיוֹם מִקְרָא קֹדֶשׁ הַזֶּה,","cond":["pesach"]},{"kind":"special","text":"לְרַחֵם בּוֹ עָלֵינוּ וּלְהוֹשִׁיעֵנוּ. זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. בִּדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וַחֲמוֹל וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["pesach"]},{"kind":"text","text":"וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים תַּחְפֹּץ בָּנוּ וְתִרְצֵנוּ, וְתֶחֱזֶינָה עֵינֵינוּ בְּשׁוּבְךָ לְצִיּוֹן בְּרַחֲמִים. בָּרוּךְ אַתָּה יִהִוִהִ, הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן.","cond":[]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שֶׁאַתָּה הוּא יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ לְעוֹלָם וָעֶד, צוּרֵנוּ צוּר חַיֵּינוּ וּמָגֵן יִשְׁעֵנוּ אַתָּה הוּא לְדֹר וָדֹר. נוֹדֶה לְּךָ וּנְסַפֵּר תְּהִלָּתֶךָ, עַל חַיֵּינוּ הַמְּסוּרִים בְּיָדֶךָ, וְעַל נִשְׁמוֹתֵינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּיךָ שֶׁבְּכָל יוֹם עִמָּנוּ, וְעַל נִפְלְאוֹתֶיךָ וְטוֹבוֹתֶיךָ שֶׁבְּכָל עֵת, עֶרֶב וָבֹקֶר וְצָהֳרָיִם. הַטּוֹב, כִּי לֹא כָלוּ רַחֲמֶיךָ, הַמְרַחֵם, כִּי לֹא תַמּוּ חֲסָדֶיךָ, כִּי מֵעוֹלָם קִוִּינוּ לָךְ.","cond":[]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת, שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה, בִּימֵי מַתִּתְיָה בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְשַׁכְּחָם תּוֹרָתָךְ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנָךְ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וּטְמֵאִים בְּיַד טְהוֹרִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, לְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמָךְ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כָּךְ בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ בְּהַלֵּל גָּמוּר וּבְהוֹדָאָה, וְעָשִׂיתָ עִמָּהֶם נִסִּים וְנִפְלָאוֹת, וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל, סֶלָה.","cond":["chanuka"]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת, שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה, בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים, בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ, וְעָשִׂיתָ עִמָּהֶם נִסִּים וְנִפְלָאוֹת, וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל, סֶלָה.","cond":["purim"]},{"kind":"text","text":"וְעַל כֻּלָּם יִתְבָּרַךְ וְיִתְרוֹמַם וְיִתְנַשֵּׂא תָמִיד, שִׁמְךָ מַלְכֵּנוּ, לְעוֹלָם וָעֶד. וְכָל הַחַיִּים יוֹדוּךָ סֶּלָה.","cond":[]},{"kind":"special","text":"וּכְתֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶךָ.","cond":["ayt"]},{"kind":"text","text":"וִיהַלְלוּ וִיבָרְכוּ אֶת שִׁמְךָ הַגָּדוֹל, בֶּאֱמֶת, לְעוֹלָם כִּי טוֹב, הָאֵל יְשׁוּעָתֵנוּ וְעֶזְרָתֵנוּ סֶלָה, הָאֵל הַטּוֹב. בָּרוּךְ אַתָּה יֻהֻוֻהֻ, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת.","cond":[]},{"kind":"text","text":"שִׂים שָׁלוֹם טוֹבָה וּבְרָכָה, חַיִּים, חֵן וָחֶסֶד, צְדָקָה וְרַחֲמִים, עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל עַמֶּךָ. וּבָרְכֵנוּ אָבִינוּ, כֻּלָּנוּ כְאֶחָד בְּאוֹר פָּנֶיךָ, כִּי בְאוֹר פָּנֶיךָ נָתַתָּ לָּנוּ יְהֹוָה אֱלֹהֵינוּ, תּוֹרָה וְחַיִּים, אַהֲבָה וָחֶסֶד, צְדָקָה וְרַחֲמִים, בְּרָכָה וְשָׁלוֹם. וְטוֹב בְּעֵינֶיךָ לְבָרְכֵנוּ וּלְבָרֵךְ אֶת כָּל עַמְּךָ יִשְׂרָאֵל בְּרֹב עֹז וְשָׁלוֹם.","cond":[]},{"kind":"special","text":"וּבְסֵפֶר חֵיִּים, בְּרָכָה וְשָׁלוֹם, וּפַרְנָסָה טוֹבָה וִישׁוּעָה וְנֶחָמָה, וּגְזֵרוֹת טוֹבוֹת, נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ, אֲנַחְנוּ וְכָל עַמְּךָ יִשְׂרָאֵל, לְחַיִּים טוֹבִים וּלְשָׁלוֹם.","cond":["ayt"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יוּהוּווּהוּ, הַמְּבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם. אָמֵן.","cond":[]},{"kind":"text","text":"יִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:","cond":[]},{"kind":"header","text":"וידוי לעיו\"כ","cond":["kipur"]},{"kind":"instruction","text":"סדר וידוי לערב יום הכיפורים","cond":["kipur"]},{"kind":"text","text":"אָנָּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, תָּבֹא לְפָנֶיךָ תְּפִלָּתֵנוּ, וְאַל תִּתְעַלַּם מַלְכֵּנוּ מִתְּחִנָּתֵנוּ, שֶׁאֵין אֲנַחְנוּ עַזֵּי פָנִים וּקְשֵׁי עֹרֶף לוֹמַר לְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ צַדִּיקִים אֲנַחְנוּ וְלֹא חָטָאנוּ, אֲבָל חָטָאנוּ, עָוִינוּ, פָּשַׁעְנוּ, אֲנַחְנוּ וַאֲבוֹתֵינוּ וְאַנְשֵׁי בֵיתֵנוּ:\n\nאָשַׁמְנוּ. בָּגַדְנוּ. גָּזַלְנוּ. דִּבַּרְנוּ דוֹפִי וְלָשׁון הָרָע. הֶעֱוִינוּ. וְהִרְשַׁעְנוּ. זַדְנוּ. חָמַסְנוּ. טָפַלְנוּ שֶׁקֶר וּמִרְמָה. יָעַצְנוּ עֵצוֹת רָעוֹת. כִּזַּבְנוּ. כָּעַסְנוּ. לַצְנוּ. מָרַדְנוּ. מָרִינוּ דְבָרֶיךָ. נִאַצְנוּ. נִאַפְנוּ. סָרַרְנוּ. עָוִינוּ. פָּשַׁעְנוּ. פָּגַמְנוּ. צָרַרְנוּ. צִעַרְנוּ אָב וָאֵם. קִשִּׁינוּ עֹרֶף. רָשַׁעְנוּ. שִׁחַתְנוּ. תִּעַבְנוּ. תָּעִינוּ וְתִעֲתַעְנוּ, וְסַרְנוּ מִמִּצְוׂתֶיךָ וּמִמִּשְׁפָּטֶיךָ הַטּוֹבִים וְלֹא שָׁוָה לָנוּ. וְאַתָּה צַדִּיק עַל כָּל הַבָּא עָלֵינוּ, כִּי אֱמֶת עָשִׂיתָ. ואֲנַחְנוּ הִרְשָׁעְנוּ:\n\nמַה נֹּאמַר לְפָנֶיךָ יוֹשֵׁב מָרוֹם, וּמַה נְּסַפֵּר לְפָנֶיךָ שׁוֹכֵן שְׁחָקִים, הֲלֹא הַנִּסְתָּרוֹת וְהַנִּגְלוֹת אַתָּה יוֹדֵעַ. אַתָּה יוֹדֵעַ רָזֵי עוֹלָם. וְתַעֲלוּמוֹת סִתְרֵי כָל חָי. אַתָּה חֹפֵשׂ כָּל חַדְרֵי בָטֶן, רוֹאֶה כְלָיוֹת וָלֵב. אֵין דָּבָר נֶעְלָם מִמֶּךָּ, וְאֵין נִסְתָּר מִנֶּגֶד עֵינֶיךָ.\nיְהִי רָצוֹן מִלְּפָנֶיךָ, יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּמְחֹל לָנוּ אֶת כָּל חַטֹּאתֵינוּ, וּתְכַפֵּר לָנוּ אֶת כָּל עֲוׂנוֹתֵינוּ, וְתִמְחֹל וְתִסְלַח לְכָל פְּשָׁעֵינוּ.\n\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּאֹנֶס.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּבְלִי דַעַת.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּגִלּוּי עֲרָיוֹת.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּדַעַת וּבְמִרְמָה.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּהִרְהוּר הַלֵּב.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּוִדּוּי פֶּה.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּזָדוֹן.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּחֹזֶק יָד.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּטֻמְאַת שְׂפָתָיִם.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּיֵצֶר הָרָע.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּיוֹדְעִים וּבְלֹא יוֹדְעִים.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּכַחַשׁ וּבְכָזָב.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּלָשׁוֹן הָרָע.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּמַרְאִית הָעָיִן.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּנֶשֶׁךְ וּבְמַרְבִּית.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּשִׂיחַ שִׂפְתוֹתֵינוּ.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בַּסֵּתֶר.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּעֵינַיִם רָמוֹת.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּפִתְחוֹן פֶּה.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּצַעֲדֵי רַגְלַיִם לְהָרָע.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּקְפִיצַת יָד.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּרָצוֹן.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּשְׁגָגָה.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּתְשׂוּמֶת יָד.\n\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּתִמְהוֹן לֵבָב.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּשִׂנְאַת חִנָּם.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּרַגְלַיִם מְמַהֲרוֹת לָרוּץ לְרָעָה.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּרְכִילוּת.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּקִשּׁוּי עֹרֶף.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּצַוָּאר עָתָק.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּפְרִיקַת עֹל.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּעַזּוּת מֶצַח.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּסִקּוּר עָיִן.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּנְטִיַּת גָּרוֹן.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּמַשָּא וּמַתָּן.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּלְשׁוֹן תַּרְמִית.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּכְנֵסִיָּה שֶׁלֹּא לְשֵׁם שָׁמָיִם.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּיוּהְרָא.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּטֻמְאַת רַעְיוֹן.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּחִלּוּל הַשֵּׁם.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּזִלְזוּל הוֹרִים וּמוֹרִים.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּוִיעוּד עֲבֵרָה.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּהוֹצָאַת דִּבָּה.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בִּדְבָרִים בְּטֵלִים.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּגַאֲוָה וָבוּז.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּגִלְגּוּל זֶה וּבְגִלְגּוּלִים אֲחֵרִים.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּבִטּוּי שְׂפָתָיִם.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בַּאֲכִילַת אִסּוּר.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ בְּמָאתַיִם וְאַרְבָּעִים וּשְׁמוֹנָה אֵבָרִים וּשְׁלשׁ מֵאוֹת וְשִׁשִּׁים וַחֲמִשָּׁה גִּידִים שֶׁל גּוּפֵנוּ וְנַפְשֵׁנוּ וְרוּחֵנוּ וְנִשְׁמָתֵנוּ וּנְשָׁמָה לְנִשְׁמָתֵנוּ.\nעַל חֵטְא שֶׁחָטָאנוּ לְפָנֶיךָ שֶׁגָּרַמְנוּ פְגַם וּמוּם בְּמָאתַיִם וְאַרְבָּעִים וּשְׁמוֹנָה אֵבָרִים וּשְׁלשׁ מֵאוֹת וְשִׁשִּׁים וַחֲמִשָּׁה גִּידִים שֶׁל אֲחֵרִים וּבְגוּפָם וְנַפְשָׁם וְרוּחָם וְנִשְׁמָתָם וּנְשָׁמָה לְנִשְׁמָתָם.\nעַל חֲטָאִים שֶׁאֲנַחְנוּ חַיָּבִים עֲלֵיהֶם עַל בִּטּוּל מִצְוׂת עֲשֵׂה.\nעַל חֲטָאִים שֶׁאֲנַחְנוּ חַיָּבִים עֲלֵיהֶם עַל לָאו הַנִּתַּק לַעֲשֵׂה.\nעַל חֲטָאִים שֶׁאֲנַחְנוּ חַיָּבִים עֲלֵיהֶם עַל לָאו שֶׁאֵין בּוֹ מַעֲשֶׂה.\nעַל חֲטָאִים שֶׁאֲנַחְנוּ חַיָּבִים עֲלֵיהֶם עֹלָה.\nעַל חֲטָאִים שֶׁאֲנַחְנוּ חַיָּבִים עֲלֵיהֶם חַטָּאת.\nעַל חֲטָאִים שֶׁאֲנַחְנוּ חַיָּבִים עֲלֵיהֶם קָרְבַּן עוֹלֶה וְיוֹרֵד.\nעַל חֲטָאִים שֶׁאֲנַחְנוּ חַיָּבִים עֲלֵיהֶם אָשָׁם תָּלוּי וְאָשָׁם וַדָּאי.\nעַל חֲטָאִים שֶׁאֲנַחְנוּ חַיָּבִים עֲלֵיהֶם מַכַּת מַרְדוּת.\nעַל חֲטָאִים שֶׁאֲנַחְנוּ חַיָּבִים עֲלֵיהֶם מַלְקוֹת אַרְבָּעִים.\nעַל חֲטָאִים שֶׁאֲנַחְנוּ חַיָּבִים עֲלֵיהֶם מִיתָה בִּידֵי שָׁמָיִם.\nעַל חֲטָאִים שֶׁאֲנַחְנוּ חַיָּבִים עֲלֵיהֶם מִיתוֹת מְשֻׁנּוֹת.\nעַל חֲטָאִים שֶׁאֲנַחְנוּ חַיָּבִים עֲלֵיהֶם כָּרֵת וַעֲרִירִי.\nעַל חֲטָאִים שֶׁאֲנַחְנוּ חַיָּבִים עֲלֵיהֶם גִּלְגּוּל בְּדוֹמֵם וְצוֹמֵחַ וְחַי בִּלְתִּי מְדַבֵּר. וְחַי מְדַבֵּר.\nעַל חֲטָאִים שֶׁאֲנַחְנוּ חַיָּבִים עֲלֵיהֶם כָּל מִינִי יִסּוּרִים.\nעַל חֲטָאִים שֶׁאֲנַחְנוּ חַיָּבִים עֲלֵיהֶם כָּל מִינִי עוֹנָשִׁים.\nעַל חֲטָאִים שֶׁאֲנַחְנוּ חַיָּבִים עֲלֵיהֶם אַרְבַּע מִיתוֹת בֵּית דִּין.\nסְקִילָה, שְׂרֵפָה, הֶרֶג וָחֶנֶק. עַל מִצְוׂת עֲשֵׂה. וְעַל מִצְוׂת לֹא תַעֲשֶׂה. בֵּין שֶׁיֵּשׁ בָּם קוּם עֲשֵׂה. וּבֵין שֶׁאֵין בָּם קוּם עֲשֵׂה. בֵּין שֶׁגְּלוּיִים לָנוּ. וּבֵין שֶׁאֵינָן גְּלוּיִים לָנוּ. אֶת שֶׁגְּלוּיִים לָנוּ כְּבָר אָמַרְנוּם לְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, וְהוֹדִינוּ לְךָ עֲלֵיהֶם. וְאֶת שֶׁאֵינָן גְּלוּיִים לָנוּ, הֵם גְּלוּיִים וִידוּעִים לְפָנֶיךָ, כִּי הַכֹּל גָּלוּי וְצָפוּי לְפָנֶיךָ יהוה אֱלֹהֵינוּ. כְּמוֹ שֶׁנֶּאֱמַר:\nהַנִּסְתָּרֹת לַיהוה אֱלֹהֵינוּ. וְהַנִּגְלֹת לָנוּ וּלְבָנֵינוּ עַד עוֹלָם לַעֲשׂוֹת אֶת כָּל דִּבְרֵי הַתּוֹרָה הַזֹּאת:\nכִּי אַתָּה סוֹלְחָן לְיִשְׂרָאֵל וּמוֹחֲלָן לְשִׁבְטֵי יְשֻׁרוּן. וּמִבַּלְעָדֶיךָ אֵין לָנוּ מֶלֶךְ מוֹחֵל וְסוֹלֵחַ.\nאְֱלֹהַי, עַד שֶׁלֹּא נוֹצַרְתִּי אֵינִי כְדַאי, וְעַכְשָׁו שֶׁנּוֹצַרְתִּי כְּאִלּוּ לֹא נוֹצַרְתִּי. עָפָר אֲנִי בְחַיָּי, קַל וָחֹמֶר בְּמִיתָתִי. הֲרֵי אֲנִי לְפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, כִּכְלִי מָלֵא בּוּשָׁה וּכְלִמָּה. (וְצָרִיךְ הָיִיתִי לוֹמַר שׁוּב לֹא אֶעֱשֶׂה, לוּלֵא כִּי יָגֹרְתִּי מֵהַיֵּצֶר הָרָע כִּי הוּא מֵאֵשׁ וַאֲנִי בָּשָׂר וָדָם וְלֹא אוּכַל לוֹ, וְאָז הָיִיתִי מוֹסִיף עַל חַטָּאתִי פֶּשַׁע. אֲבָל) יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁלֹּא אֶחֱטָא עוֹד. וּמַה שֶּׁחָטָאתִי לְפָנֶיךָ מְחֹק בְּרַחֲמֶיךָ הָרַבִּים, אֲבָל לֹא עַל יְדֵי יִסּוּרִין וְחוֹלָאִים רָעִים.","cond":["kipur"]},{"kind":"text","text":"אֱלֹהַי, נְצֹר לְשׁוֹנִי מֵרָע, וּשְׂפָתַי מִדַּבֵּר מִרְמָה, וְלִמְקַלְלַי נַפְשִׁי תִדֹּם, וְנַפְשִׁי כֶּעָפָר לַכֹּל תִּהְיֶה. פְּתַח לִבִּי בְּתוֹרָתֶךָ, וְאַחֲרֵי מִצְוׂתֶיךָ תִּרְדֹּף נַפְשִׁי. וְכָל הַקָּמִים עָלַי לְרָעָה, מְהֵרָה הָפֵר עֲצָתָם וְקַלְקֵל מַחְשְבוֹתָם. (יִהְיוּ כְּמֹץ לִפְנֵי רוּחַ, וּמַלְאַךְ יהוה דּוֹחֶה.) עֲשֵׂה לְמַעַן שְׁמָךְ, עֲשֵׂה לְמַעַן יְמִינָךְ, עֲשֵׂה לְמַעַן תּוֹרָתָךְ, עֲשֵׂה לְמַעַן קְדֻשָּׁתָךְ, לְמַעַן יֵחָלְצוּן יְדִידֶיךָ. הוֹשִׁיעָה יְמִינְךָ וַעֲנֵנִי.\nיִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:","cond":[]},{"kind":"instruction","text":"יש נוהגים לומר כאן תחנונים, ויש אומרים תפילה זו:\nיְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁלֹּא תַעֲלֶה קִנְאַת אֲחֵרִים עָלַי וְלֹא קִנְאָתִי עַל אֲחֵרִים, וְשֶׁלֹּא אֶכְעוֹס הַיּוֹם וְשֶׁלֹּא אַכְעִיסֶך, וְתַצִּילֵנִי מִיֵּצֶר הָרָע, וְתֵן בְּלִבִּי הַכְנָעָה וַעֲנָוָה וְיִרְאַת חֵטְא. מַלְכֵּנוּ וֵאלֹהֵינוּ, יַחֵד שִׁמְךָ בְּעוֹלָמָךְ וּבְנֵה בֵיתָךְ, שַׁכְלֵל הֵיכָלָךְ וְקַבֵּץ גָּלֻיּוֹתֵינוּ, פְּדֵה צֹאנָךְ וְשַמַּח עֲדָתָךְ בִּמְהֵרָה בְיָמֵינוּ וְתֵן חֶלְקֵנוּ בְּתוֹרָתָךְ. אָמֵן.","cond":[]},{"kind":"text","text":"עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּבְנֶה בֵית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵינוּ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתָךְ לַעֲשׂוֹת חֻקֵּי רְצוֹנָךְ וּלְעָבְדָךְ בְּלֵבָב שָׁלֵם.","cond":[]},{"kind":"header","text":"חזרת הש\"ץ","cond":[]},{"kind":"instruction","text":"חזרת הש\"ץ","cond":[]},{"kind":"text","text":"אֲדֹנָי, שְׂפָתַי תִּפְתָּח, וּפִי יַגִּיד תְּהִלָּתֶךָ:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יְהֹוָה, אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק וֵאלֹהֵי יַעֲקֹב, הָאֵל הַגָּדוֹל, הַגִּבּוֹר וְהַנּוֹרָא, אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, קוֹנֵה הַכֹּל וְזוֹכֵר חַסְדֵי אָבוֹת וּמֵבִיא גּוֹאֵל לִבְנֵי בְנֵיהֶם לְמַעַן שְׁמוֹ בְּאַהֲבָה.","cond":[]},{"kind":"special","text":"זָכְרֵנוּ לְחַיִּים, מֶלֶךְ חָפֵץ בַּחַיִּים, כָּתְבֵנוּ בְּסֵפֶר חַיִּים, לְמַעַנְךָ אֱלֹהִים חַיִּים.","cond":["ayt"]},{"kind":"text","text":"מֶלֶךְ עוֹזֵר וּמוֹשִׁיעַ וּמָגֵן. בָּרוּךְ אַתָּה יַהַוַהַ, מָגֵן אַבְרָהָם.","cond":[]},{"kind":"text","text":"אַתָּה גִּבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֵּה מֵתִים אַתָּה, רַב לְהוֹשִׁיעַ,","cond":[]},{"kind":"summer","text":"מוֹרִיד הַטָּל,","cond":["summerTal"]},{"kind":"winter","text":"מַשִּׁיב הָרוּחַ וּמוֹרִיד הַגֶּשֶׁם,","cond":["winterTal"]},{"kind":"text","text":"מְכַלְכֵּל חַיִּים בְּחֶסֶד, מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים, סוֹמֵךְ נוֹפְלִים וְרוֹפֵא חוֹלִים, וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמוּנָתוֹ לִישֵׁנֵי עָפָר. מי כָמוֹךָ בַּעַל גְּבוּרוֹת וּמִי דוֹמֶה לָךְ, מֶלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִיחַ יְשׁוּעָה.","cond":[]},{"kind":"special","text":"מִי כָמוֹךָ אַב הָרַחֲמָן, זוֹכֵר יְצוּרָיו בְּרַחֲמִים לְחַיִּים.","cond":["ayt"]},{"kind":"text","text":"וְנֶאֱמָן אַתָּה לְהַחֲיוֹת מֵתִים. בָּרוּךְ אַתָּה יֵהֵוֵהֵ, מְחַיֵּה הַמֵּתִים.","cond":[]},{"kind":"header","text":"קדושה","cond":[]},{"kind":"instruction","text":"קדושה בחזרת הש\"ץ","cond":[]},{"kind":"text","text":"נַקְדִּישָׁךְ וְנַעֲרִיצָךְ כְּנֹעַם שִׂיחַ סוֹד שַׂרְפֵי קֹדֶשׁ, הַמְשַׁלְּשִׁים לְךָ קְדֻשָּׁה, כַּכָּתוּב עַל יַד נְבִיאֶךָ: וְקָרָא זֶה אֶל זָה וְאָמַר: קָדוֹש, קָדוֹש, קָדוֹש, יהוה צְבָאוֹת, מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ:\nלְעֻמָּתָם מְשַׁבְּחִים וְאוֹמְרִים: בָּרוּךְ כְּבוֹד יהוה מִמְּקוֹמוֹ:\nוּבְדִבְרֵי קָדְשְׁךָ כָּתוּב לֵאמֹר: יִמְלֹךְ יהוה לְעוֹלָם, אֱלֹהַיִךְ צִיּוֹן לְדֹר וָדֹר, הַלְלוּיָהּ:","cond":[]},{"kind":"text","text":"אַתָּה קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ, וּקְדוֹשִׁים בְּכָל-יוֹם יְהַלְלוּךָ סֶּלָה.","cond":[]},{"kind":"special","text":"בָּרוּךְ אַתָּה יֹהֵוָה, הַמֶּלֶךְ הַקָּדוֹשׁ.","cond":["ayt"]},{"kind":"text","text":"בּרוּךְ אַתָּה יֹהֵוָה, הָאֵל הַקָּדוֹשׁ.","cond":["noayt"]},{"kind":"text","text":"אַתָּה חוֹנֵן לְאָדָם דַּעַת וּמְלַמֵּד לֶאֱנוֹשׁ בִּינָה. וְחָנֵּנוּ מֵאִתְּךָ חָכְמָה בִּינָה וָדָעַת. בָּרוּךְ אַתָּה יַהַוַהַ חוֹנֵן הַדָּעַת.","cond":[]},{"kind":"text","text":"הֲשִׁיבֵנוּ אָבִינוּ לְתוֹרָתֶךָ, וְקָרְבֵנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶךָ, וְהַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ. בָּרוּךְ אַתָּה יֵהֵוֵהֵ, הָרוֹצֶה בִּתְשׁוּבָה.","cond":[]},{"kind":"text","text":"סְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחֹל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ, כִּי אֵל טוֹב וְסַלָּח אָתָּה. בָּרוּךְ אַתָּה יֶהֶוֶהֶ, חַנּוּן הַמַּרְבֶּה לִסְלֹחַ.","cond":[]},{"kind":"text","text":"רְאֵה נָא בְעָנְיֵנוּ וְרִיבָה רִיבֵנוּ, וּמַהֵר לְגָאֳלֵנוּ גְאֻלָּה שְׁלֵמָה לְמַעַן שְׁמֶךָ, כִּי אֵל גּוֹאֵל חָזָק אָתָּה. בָּרוּךְ אַתָּה יְהְוְהְ, גוֹאֵל יִשְׂרָאֵל.","cond":[]},{"kind":"instruction","text":"בתענית ציבור אומר כאן השליח ציבור \"עננו\".","cond":["taanit"]},{"kind":"special","text":"עֲנֵנוּ אָבִינוּ עֲנֵנוּ בְּיוֹם צוֹם הַתַּעֲנִית הַזֶּה, כִּי בְצָרָה גְדוֹלָה אֲנָחְנוּ. אַל תֵּפֶן לְרִשְׁעֵנוּ, וְאַל תִּתְעַלַּם מַלְכֵּנוּ מִבַּקָּשָׁתֵנוּ, הֱיֵה נָא קָרוֹב לְשַׁוְעָתֵנוּ. טֶרֶם נִקְרָא אֵלֶיךָ אַתָּה תַעֲנֶה, נְדַבֵּר וְאַתָּה תִשְׁמַע, כַּדָּבָר שֶׁנֶּאֱמַר: וְהָיָה טֶרֶם יִקְרָאוּ וַאֲנִי אֶעֱנֶה, עוֹד הֵם מְדַבְּרִים וַאֲנִי אֶשְׁמָע: כִּי אַתָּה יהוה פּוֹדֶה וּמַצִּיל וְעוֹנֶה וּמְרַחֵם בְּכָל עֵת צָרָה וְצוּקָה. בָּרוּךְ אַתָּה יהוה, הָעוֹנֶה לְעַמּוֹ יִשְׂרָאֵל בְּעֵת צָרָה.","cond":["taanit"]},{"kind":"text","text":"רְפָאֵנוּ יְהֹוָה וְנֵרָפֵא, הוֹשִׁיעֵנוּ וְנִוָּשֵׁעָה כִּי תְהִלָּתֵנוּ אָתָּה, וְהַעֲלֵה אֲרוּכָה וּמַרְפֵּא לְכָל-תַּחֲלוּאֵינוּ וּלְכָל-מַכְאוֹבֵינוּ וּלְכָל-מַכּוֹתֵינוּ, כִּי אֵל רוֹפֵא רַחֲמָן וְנֶאֱמָן אָתָּה. בָּרוּךְ אַתָּה יֹהֹוׂהֹ, רוֹפֵא חוֹלֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"summer","text":"בָּרְכֵנוּ יְהֹוָה אֱלֹהֵינוּ בְּכָל מַעֲשֵׂי יָדֵינוּ, וּבָרֵךְ שְׁנָתֵנוּ בְּטַלְלֵי רָצוֹן בְּרָכָה וּנְדָבָה, וּתְהִי אַחֲרִיתָהּ חַיִּים וְשָׂבָע וְשָׁלוֹם כַּשָּׁנִים הַטּוֹבוֹת לִבְרָכָה. כִּי אֵל טוֹב וּמֵטִיב אַתָּה וּמְבָרֵךְ הַשָּׁנִים. בָּרוּךְ אַתָּה יִהִוִהִ, מְבָרֵךְ הַשָּׁנִים.","cond":["summerBracha"]},{"kind":"winter","text":"בָּרֵךְ עָלֵינוּ יְהֹוָה אֱלֹהֵינוּ אֶת הַשָּׁנָה הַזֹּאת וְאֶת כָּל מִינֵי תְּבוּאָתָהּ לְטוֹבָה, וְתֵן טַל וּמָטָר לִבְרָכָה עַל כָּל פְּנֵי הָאֲדָמָה, וְרַוֵּה פְּנֵי תֵבֵל וְשַׂבַּע אֶת הָעוֹלָם כֻּלּוֹ מִטּוּבָךְ, וּמַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ וּמֵעֹשֶׁר מַתְּנוֹת יָדֶיךָ. שָׁמְרָה וְהַצִּילָה שָׁנָה זוֹ מִכָּל דָּבָר רָע וּמִכָּל מִינֵי מַשְׁחִית וּמִכָּל מִינֵי פֻרְעָנוּת, וַעֲשֵׂה לָהּ תִּקְוָה טוֹבה וְאַחֲרִית שָׁלוֹם. חוּס וְרַחֵם עָלֶיהָ וְעַל כָּל תְּבוּאָתָהּ וּפֵירוֹתֶיהָ, וּבָרְכָהּ בְּגִשְׁמֵי רָצוֹן בְּרָכָה וּנְדָבָה, וּתְהִי אַחֲרִיתָהּ חַיִּים וְשָׂבָע וְשָׁלוֹם כַּשָּׁנִים הַטּוֹבוֹת לִבְרָכָה. כִּי אֵל טוֹב וּמֵטִיב אַתָּה וּמְבָרֵךְ הַשָּׁנִים. בָּרוּךְ אַתָּה יִהִוִהִ, מְבָרֵךְ הַשָּׁנִים.","cond":["winterBracha"]},{"kind":"text","text":"תְּקַע בְּשׁוֹפָר גָּדוֹל לְחֵרוּתֵנוּ, וְשָׂא נֵס לְקַבֵּץ גָּלֻיּוֹתֵינוּ, וְקַבְּצֵנוּ יַחַד מֵאַרְבַּע כַּנפוֹת הָאָרֶץ לְאַרְצֵנוּ. בָּרוּךְ אַתָּה יֻהֻוֻהֻ, מְקַבֵּץ נִדְחֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"הָשִׁיבָה שׁוֹפְטֵינוּ כְּבָרִאשׁוֹנָה, וְיוֹעֲצֵינוּ כְּבַתְּחִלָּה, וְהָסֵר מִמֶּנוּ יָגוֹן וַאֲנָחָה, וּמְלֹךְ עָלֵינוּ מְהֵרָה אַתָּה יְהֹוָה לְבַדְּךָ, בְּחֶסֶד וּבְרַחֲמִים, בְּצֶדֶק וּבְמִשְׁפָּט.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יוּהוּווּהוּ, מֶלֶךְ אוֹהֵב צְדָקָה וּמִשְׁפָּט.","cond":["noAyt"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יוּהוּווּהוּ, הַמֶּלֶךְ הַמִּשְׁפָּט.","cond":["ayt"]},{"kind":"text","text":"לַמִּינִים וְלַמַּלְשִׁינִים אַל תְּהִי תִקְוָה, וְכָל הַזֵּדִים כְּרֶגַע יֹאבֵדוּ, וְכָל אוֹיְבֶיךָ וְכָל שׂוֹנְאֶיךָ מְהֵרָה יִכָּרֵתוּ, וּמַלְכוּת הָרִשְׁעָה מְהֵרָה תְעַקֵּר וּתְשַׁבֵּר וּתְכַלֵּם וְתַכְנִיעֵם בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יָהָוָהָ, שׁוֹבֵר אוֹיְבִים וּמַכְנִיעַ זֵדִים.","cond":[]},{"kind":"text","text":"עַל הַצַּדִּיקִים וְעַל הַחֲסִידִים וְעַל שְׁאֵרִית עַמְּךָ בֵּית יִשְׂרָאֵל וְעַל זִקְנֵיהֶם וְעַל פְּלֵטַת בֵּית סוֹפְרֵיהֶם וְעַל גֵּרֵי הַצֶּדֶק וְעָלֵינוּ, יֶהֱמוּ נָא רַחֲמֶיךָ יְהֹוָה אֱלֹהֵינוּ, וְתֵן שָׂכָר טוֹב לְכָל הַבּוֹטְחִים בְּשִׁמְךָ בֶאֱמֶת, וְשִׂים חֶלְקֵנוּ עִמָּהֶם, וּלְעוֹלָם לֹא נֵבוֹשׁ כִּי בְךָ בָטַחְנוּ, וְעַל חַסְדְּךָ הַגָּדוֹל בֶּאֱמֶת נִשְׁעָנְנוּ. בָּרוּךְ אַתָּה יוּהוּווּהוּ, מִשְׁעָן וּמִבְטָח לַצַּדִּיקִים.","cond":[]},{"kind":"text","text":"תִּשְׁכּוֹן בְּתוֹךְ יְרוּשָׁלַיִם עִירְךָ כַּאֲשֶׁר דִּבַּרְתָּ, וְכִסֵּא דָוִד עַבְדְּךָ מְהֵרָה בְתוֹכָהּ תָּכִין, וּבְנֵה אוֹתָהּ בִּנְיַן עוֹלָם בִּמְהֵרָה בְיָמֵינוּ.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יֻהֻוֻהֻ, בּוֹנֵה יְרוּשָׁלָיִם.","cond":["noTishaaBeav"]},{"kind":"special","text":"נַחֵם יהוה אֱלֹהֵינוּ אֶת אֲבֵלֵי צִיּוֹן וְאֶת אֲבֵלֵי יְרוּשָׁלַיִם, וְאֶת הָעִיר הַחֲרֵבָה וְהַבְּזוּיָה וְהַשוֹמֵמָה, מִבְּלִי בָנֶיהָ הִיא יוֹשֶׁבֶת, וְרֹאשָׁהּ חָפוּי כְּאִשָּׁה עֲקָרָה שֶׁלֹּא יָלָדָה. וַיְבַלְּעוּהָ לִגְיוֹנִים וַיִּירָשׁוּהָ, וַיַטִּילוּ אֶת עַמְּךָ יִשְׂרָאֵל לַחֶרֶב, וַיַּהַרְגוּ בְזָדוֹן חֲסִידָי עֶלְיוֹן. עַל כֵּן צִיּוֹן בְּמֶרֶר תִּבְכֶּה וִירוּשָׁלַיִם תִּתֵּן קוֹלָהּ. לִבִּי לִבִּי עַל חַלְלֵיהֶם, מֵעַי מֵעַי עַל הֲרוּגֵיהֶם. כִּי אַתָּה יהוה בָּאֵשׁ הִצַּתָּהּ, וּבָאֵשׁ אַתָּה עָתִיד לִבְנוֹתָהּ, כַּכָּתוּב: וַאֲנִי אֶהְיֶה לָהּ נְאֻם יְהוה חוֹמַת אֵשׁ סָבִיב, וּלְכָבוֹד אֶהְיֶה בְתוֹכָהּ: בָּרוּךְ אַתָּה יהוה, מְנַחֵם צִיּוֹן בְּבִנְיַן יְרוּשָׁלַיִם.","cond":["tishaaBeav"]},{"kind":"text","text":"אֶת צֶמַח דָּוִד עַבְדְּךָ מְהֵרָה תַצְמִיחַ, וְקַרְנוֹ תָרוּם בִּישׁוּעָתֶךָ. כִּי לִישׁוּעָתְךָ קִוִּינוּ וְצִפִּינוּ כָּל הַיּוֹם. בָּרוּךְ אַתָּה יִהִוִהִ, מַצְמִיחַ קֶרֶן יְשׁוּעָה.","cond":[]},{"kind":"text","text":"שְׁמַע קוֹלֵנוּ יְהֹוָה אֱלֹהֵינוּ, אָב הָרַחֲמָן רַחֵם עָלֵינוּ, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ, כִּי אֵל שׁוֹמֵעַ תְּפִלּוֹת וְתַחֲנוּנִים אָתָּה, וּמִלְּפָנֶיךָ מַלְכֵּנוּ, רֵיקָם אַל תְּשִׁיבֵנוּ. חָנֵּנוּ וַעֲנֵנוּ וּשְׁמַע תְּפִלָּתֵנוּ. כִּי אַתָּה שׁוֹמֵעַ תְּפִלַּת כָּל פֶּה. בָּרוּךְ אַתָּה יהוה, שׁוֹמֵעַ תְּפִלָּה.","cond":[]},{"kind":"text","text":"רְצֵה יְהֹוָה אֱלֹהֵינוּ בְּעַמְּךָ יִשְׂרָאֵל, וּלִתְפִלָּתָם שְׁעֵה, וְהָשֵׁב הָעֲבוֹדָה לִדְבִיר בֵּיתֶךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם מְהֵרָה בְאַהֲבָה תְּקַבֵּל בְּרָצוֹן, וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּךָ.","cond":[]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, זִכְרוֹן יְרוּשָׁלַיִם עִירָךְ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן לְחֶסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["rh"]},{"kind":"special","text":"רֹאשׁ הַחֹדֶשׁ הַזֶּה,","cond":["rh"]},{"kind":"special","text":"לְרַחֵם בּוֹ עָלֵינוּ וּלְהוֹשִׁיעֵנוּ. זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. בִּדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וַחֲמוֹל וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["rh"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, זִכְרוֹן יְרוּשָׁלַיִם עִירָךְ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן לְחֶסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["sucot"]},{"kind":"special","text":"חַג הַסֻּכּוֹת הַזֶּה, בְּיוֹם מִקְרָא קֹדֶשׁ הַזֶּה,","cond":["sucot"]},{"kind":"special","text":"לְרַחֵם בּוֹ עָלֵינוּ וּלְהוֹשִׁיעֵנוּ. זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. בִּדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וַחֲמוֹל וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["sucot"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, זִכְרוֹן יְרוּשָׁלַיִם עִירָךְ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן לְחֶסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["pesach"]},{"kind":"special","text":"חַג הַמַּצּוֹת הַזֶּה, בְּיוֹם מִקְרָא קֹדֶשׁ הַזֶּה,","cond":["pesach"]},{"kind":"special","text":"לְרַחֵם בּוֹ עָלֵינוּ וּלְהוֹשִׁיעֵנוּ. זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. בִּדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וַחֲמוֹל וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["pesach"]},{"kind":"text","text":"וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים תַּחְפֹּץ בָּנוּ וְתִרְצֵנוּ, וְתֶחֱזֶינָה עֵינֵינוּ בְּשׁוּבְךָ לְצִיּוֹן בְּרַחֲמִים. בָּרוּךְ אַתָּה יִהִוִהִ, הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן.","cond":[]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שֶׁאַתָּה הוּא יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ לְעוֹלָם וָעֶד, צוּרֵנוּ צוּר חַיֵּינוּ וּמָגֵן יִשְׁעֵנוּ אַתָּה הוּא לְדֹר וָדֹר. נוֹדֶה לְּךָ וּנְסַפֵּר תְּהִלָּתֶךָ, עַל חַיֵּינוּ הַמְּסוּרִים בְּיָדֶךָ, וְעַל נִשְׁמוֹתֵינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּיךָ שֶׁבְּכָל יוֹם עִמָּנוּ, וְעַל נִפְלְאוֹתֶיךָ וְטוֹבוֹתֶיךָ שֶׁבְּכָל עֵת, עֶרֶב וָבֹקֶר וְצָהֳרָיִם. הַטּוֹב, כִּי לֹא כָלוּ רַחֲמֶיךָ, הַמְרַחֵם, כִּי לֹא תַמּוּ חֲסָדֶיךָ, כִּי מֵעוֹלָם קִוִּינוּ לָךְ.","cond":[]},{"kind":"header","text":"מודים דרבנן","cond":[]},{"kind":"instruction","text":"מודים דרבנן:","cond":[]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שֶׁאַתָּה הוּא יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי כָל בָּשָׁר, יוֹצְרֵנוּ יוֹצֵר בְּרֵאשִׁית. בְּרָכוֹת וְהוֹדָאוֹת לְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ, עַל שֶׁהֶחֱיִיתָנוּ וְקִיַּמְתָּנוּ. כֵּן תְּחַיֵּנוּ וּתְחָנֵּנוּ וְתֶאֱסוֹף גָּלֻיּוֹתֵינוּ לְחַצְרוֹת קָדְשֶׁךָ, לִשְׁמֹר חֻקֶּיךָ וְלַעֲשׂוֹת רְצוֹנְךָ וּלְעָבְדְךָ בְלֵבָב שָׁלֵם, עַל שֶׁאֲנַחְנוּ מוֹדִים לָךְ, בָּרוּךְ אֵל הַהוֹדָאוֹת.","cond":[]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת, שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה, בִּימֵי מַתִּתְיָה בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְשַׁכְּחָם תּוֹרָתָךְ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנָךְ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וּטְמֵאִים בְּיַד טְהוֹרִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, לְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמָךְ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כָּךְ בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ בְּהַלֵּל גָּמוּר וּבְהוֹדָאָה, וְעָשִׂיתָ עִמָּהֶם נִסִּים וְנִפְלָאוֹת, וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל, סֶלָה.","cond":["chanuka"]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת, שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה, בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים, בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ, וְעָשִׂיתָ עִמָּהֶם נִסִּים וְנִפְלָאוֹת, וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל, סֶלָה.","cond":["purim"]},{"kind":"text","text":"וְעַל כֻּלָּם יִתְבָּרַךְ וְיִתְרוֹמַם וְיִתְנַשֵּׂא תָמִיד, שִׁמְךָ מַלְכֵּנוּ, לְעוֹלָם וָעֶד. וְכָל הַחַיִּים יוֹדוּךָ סֶּלָה.","cond":[]},{"kind":"special","text":"וּכְתֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶךָ.","cond":["ayt"]},{"kind":"text","text":"וִיהַלְלוּ וִיבָרְכוּ אֶת שִׁמְךָ הַגָּדוֹל, בֶּאֱמֶת, לְעוֹלָם כִּי טוֹב, הָאֵל יְשׁוּעָתֵנוּ וְעֶזְרָתֵנוּ סֶלָה, הָאֵל הַטּוֹב. בָּרוּךְ אַתָּה יֻהֻוֻהֻ, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת.","cond":[]},{"kind":"header","text":"ברכת כהנים","cond":["taanit"]},{"kind":"instruction","text":"ברכת כהנים לחזרת הש\"ץ:\n\nאם לא עלו כהנים לדוכן הש\"ץ אומר או\"א (נמצא בהמשך).\n\nאם עלו שני כהנים לדוכן קוראים להם - כֹּהֲנִים:\n\nהכהנים מברכים:","cond":["taanit"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בִּקְדֻשָּׁתוֹ שֶׁל אַהֲרֹן, וְצִוָּנוּ לְבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בְּאַהֲבָה.\n\nיְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ:\nיָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ:\nיִשָּׂא יהוה פָּנָיו אֵלֶיךָ וְיָשֵׂם לְךָ שָׁלוֹם:","cond":["taanit"]},{"kind":"instruction","text":"הקהל אומר:","cond":["taanit"]},{"kind":"text","text":"אַדִּיר בַּמָּרוֹם שׁוֹכֵן בִּגְבוּרָה, אַתָּה שָׁלוֹם וְשִׁמְךָ שָׁלוֹם. יְהִי רָצוֹן שֶׁתָּשִׂים עָלֵינוּ וְעַל כָּל עַמְּךָ בֵּית יִשְׂרָאֵל חַיִּים וּבְרָכָה לְמִשְׁמֶרֶת שָׁלוֹם.","cond":["taanit"]},{"kind":"instruction","text":"הכהנים אומרים","cond":["taanit"]},{"kind":"text","text":"רִבּוֹנוֹ שֶׁל עוֹלָם, עָשִׂינוּ מַה שֶּׁגָּזַרְתָּ עָלֵינוּ, אַף אַתָּה עֲשֵׂה עִמָּנוּ כְּמוֹ שֶׁהִבְטַחְתָּנוּ: הַשְׁקִיפָה מִמְּעוֹן קָדְשְׁךָ מִן הַשָּׁמַיִם, וּבָרֵךְ אֶת עַמְּךָ אֶת יִשְׂרָאֵל, וְאֵת הָאֲדָמָה אֲשֶׁר נָתַתָּה לָנוּ, כַּאֲשֶׁר נִשְׁבַּעְתָּ לַאֲבֹתֵינוּ, אֶרֶץ זָבַת חָלָב וּדְבָשׁ:","cond":["taanit"]},{"kind":"instruction","text":"אם לא עלו כהנים לדוכן הש\"ץ אומר:","cond":["taanit"]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, בָּרְכֵנוּ בַּבְּרָכָה הַמְשֻׁלֶּשֶׁת בַּתּוֹרָה הַכְּתוּבָה עַל יְדֵי מֹשֶׁה עַבְדֶּךָ, הָאֲמוּרָה מִפִּי אַהֲרֹן וּבָנָיו כֹּהֲנִים עַם קְדוֹשֶׁךָ, כָּאָמוּר: יְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ: יָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ: יִשָּׂא יהוה פָּנָיו אֵלֶיךָ וְיָשֵׂם לְךָ שָׁלוֹם:","cond":["taanit"]},{"kind":"text","text":"שִׂים שָׁלוֹם טוֹבָה וּבְרָכָה, חַיִּים, חֵן וָחֶסֶד, צְדָקָה וְרַחֲמִים, עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל עַמֶּךָ. וּבָרְכֵנוּ אָבִינוּ, כֻּלָּנוּ כְאֶחָד בְּאוֹר פָּנֶיךָ, כִּי בְאוֹר פָּנֶיךָ נָתַתָּ לָּנוּ יְהֹוָה אֱלֹהֵינוּ, תּוֹרָה וְחַיִּים, אַהֲבָה וָחֶסֶד, צְדָקָה וְרַחֲמִים, בְּרָכָה וְשָׁלוֹם. וְטוֹב בְּעֵינֶיךָ לְבָרְכֵנוּ וּלְבָרֵךְ אֶת כָּל עַמְּךָ יִשְׂרָאֵל בְּרֹב עֹז וְשָׁלוֹם.","cond":[]},{"kind":"special","text":"וּבְסֵפֶר חֵיִּים, בְּרָכָה וְשָׁלוֹם, וּפַרְנָסָה טוֹבָה וִישׁוּעָה וְנֶחָמָה, וּגְזֵרוֹת טוֹבוֹת, נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ, אֲנַחְנוּ וְכָל עַמְּךָ יִשְׂרָאֵל, לְחַיִּים טוֹבִים וּלְשָׁלוֹם.","cond":["ayt"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יוּהוּווּהוּ, הַמְּבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם. אָמֵן.","cond":[]},{"kind":"text","text":"יִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:","cond":[]},{"kind":"header","text":"אבינו מלכנו","cond":["ayt"]},{"kind":"instruction","text":"אבינו מלכנו","cond":["ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חָטָאנוּ לְפָנֶיךָ רַחֵם עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, אֵין לָנוּ מֶלֶךְ אֶלָּא אָתָּה.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה עִמָּנוּ לְמַעַן שְׁמֶךָ.\nאָבִינוּ מַלְכֵּנוּ, חַדֵּשׁ עָלֵינוּ שָׁנָה טובָה וּמְבֹרֶכֶת.\nאָבִינוּ מַלְכֵּנוּ, בַּטֵּל מֵעָלֵינוּ כָּל גְּזֵרות קָשׁות וְרָעות.\nאָבִינוּ מַלְכֵּנוּ, בַּטֵּל מַחְשְׁבות שׂוֹנְאֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, הָפֵר עֲצַת אוֹיְבֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה כָּל צַר וּמַשְׂטִין מֵעָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה דֶבֶר וְחֶרֶב וְרָעָה וְרָעָב וּשְׁבִי וּבִזָּה וּמַשְׁחִית וּמַגֵּפָה וְשָׂטָן וְיֵצֶר הָרָע וָחֳלָאִים רָעִים מִבְּנֵי בְרִיתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, שְׁלַח רְפוּאָה שְׁלֵמָה לְכָל-חוֹלֵי עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, מְנַע מַגֵּפָה מִנַּחֲלָתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, זְכֹר כִּי עָפָר אֲנָחְנוּ.\nאָבִינוּ מַלְכֵּנוּ, מְחֹל וּסְלַח לְכָל עֲוׂנוֹתֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, קְרַע רוֹעַ גְּזַר-דִּינֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, מְחֹק בְּרַחֲמֶיךָ הָרַבִּים כָּל-שִׁטְרֵי חוֹבוֹתֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, מְחֵה וְהַעֲבֵר פְּשָׁעֵינוּ מִנֶּגֶד עֵינֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר חַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר צַדִּיקִים וַחֲסִידִים.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר יְשָׁרִים וּתְמִימִים.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר פַּרְנָסָה וְכַלְכָּלָה טוֹבָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר מְחִילָה וּסְלִיחָה וְכַפָּרָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר גְּאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ בְּזִכְרוֹן טוֹב מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, הַצְמַח לָנוּ יְשׁוּעָה בְּקָרוב.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן יִשְׂרָאֵל עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, וְהָרֵם קֶרֶן מְשִׁיחֶךָ.\nאָבִינוּ מַלְכֵּנוּ, חָנֵּנוּ וַעֲנֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, הַחֲזִירֵנוּ בִתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, שְׁמַע קולֵנוּ, חוּס וְרַחֵם עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעֲנָךְ, אִם לא לְמַעֲנֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, קַבֵּל בְּרַחֲמִים וּבְרָצון אֶת תְּפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, אַל תְּשִׁיבֵנוּ רֵיקָם מִלְּפָנֶיךָ.","cond":["ayt"]},{"kind":"header","text":"תחנון","cond":["minchaTachanun"]},{"kind":"instruction","text":"יש נוהגים שלא לומר תחנון היום, ובפרט בארץ ישראל שיכולים בקלות להגיע לירושלים לשמוח עימם בשמחת פורים דמוקפין.","cond":["minchaTachanun","purim_meshulash_tachanun_message"]},{"kind":"text","text":"אָנָּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, תָּבֹא לְפָנֶיךָ תְּפִלָּתֵנוּ, וְאַל תִּתְעַלַּם מַלְכֵּנוּ מִתְּחִנָּתֵנוּ, שֶׁאֵין אֲנַחְנוּ עַזֵּי פָנִים וּקְשֵׁי עֹרֶף לוֹמַר לְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ צַדִּיקִים אֲנַחְנוּ וְלֹא חָטָאנוּ, אֲבָל חָטָאנוּ, עָוִינוּ, פָּשַׁעְנוּ, אֲנַחְנוּ וַאֲבוֹתֵינוּ וְאַנְשֵׁי בֵיתֵנוּ:\n\nאָשַׁמְנוּ. בָּגַדְנוּ. גָּזַלְנוּ. דִּבַּרְנוּ דוֹפִי וְלָשׁון הָרָע. הֶעֱוִינוּ. וְהִרְשַׁעְנוּ. זַדְנוּ. חָמַסְנוּ. טָפַלְנוּ שֶׁקֶר וּמִרְמָה. יָעַצְנוּ עֵצוֹת רָעוֹת. כִּזַּבְנוּ. כָּעַסְנוּ. לַצְנוּ. מָרַדְנוּ. מָרִינוּ דְבָרֶיךָ. נִאַצְנוּ. נִאַפְנוּ. סָרַרְנוּ. עָוִינוּ. פָּשַׁעְנוּ. פָּגַמְנוּ. צָרַרְנוּ. צִעַרְנוּ אָב וָאֵם. קִשִּׁינוּ עֹרֶף. רָשַׁעְנוּ. שִׁחַתְנוּ. תִּעַבְנוּ. תָּעִינוּ וְתִעֲתַעְנוּ, וְסַרְנוּ מִמִּצְוׂתֶיךָ וּמִמִּשְׁפָּטֶיךָ הַטּוֹבִים וְלֹא שָׁוָה לָנוּ. וְאַתָּה צַדִּיק עַל כָּל הַבָּא עָלֵינוּ, כִּי אֱמֶת עָשִׂיתָ. ואֲנַחְנוּ הִרְשָׁעְנוּ:","cond":["minchaTachanun"]},{"kind":"instruction","text":"יחיד אינו אומר זה ולא הי\"ג מדות:","cond":["minchaTachanun"]},{"kind":"text","text":"אֵל אֶרֶךְ אַפַּיִם אַתָּה וּבַעַל הָרַחֲמִים. גְּדֻלַּת רַחֲמֶיךָ וַחֲסָדֶיךָ תִּזְכּר הַיּוֹם לְזֶרַע יְדִידֶיךָ, כְּמוֹ שְהוֹדַעְתָּ לֶעָנָו מִקֶּדֶם. וְכֵן כָּתוּב בְּתוֹרָתָךְ: וַיֵּרֶד יהוה בֶּעָנָן וַיִּתְיַצֵּב עִמּו שָׁם, וַיִּקְרָא בְשֵׁם, יהוה: וְשָׁם נֶאֱמַר:\nוַיַעֲבֹר יהוה עַל פָּנָיו וַיִּקְרָא:\nיהוה, יהוה, (א) אֵל (ב) רַחוּם (ג) וְחַנּוּן, (ד) אֶרֶך (ה) אַפַּיִם, (ו) וְרַב-חֶסֶד (ז) וֶאֱמֶת: (ח) נֹצֵר חֶסֶד (ט) לָאֲלָפִים, (י) נֹשֵׂא עָוׂן (יא) וָפֶשַע (יב) וְחַטָּאָה, (יג) ונקה.\n\nרַחוּם וְחַנּוּן חָטָאנוּ לְפָנֶיךָ רַחֵם עָלֵינוּ וְהושִׁיעֵנוּ.\n\nלְדָוִד, אֵלֶיךָ יהוה נַפְשִׁי אֶשָּׂא: אֱלֹהַי, בְּךָ בָטַחְתִּי אַל אֵבוֹשָׁה, אַל יַעַלְצוּ אֹיְבַי לִי: גַּם כָּל קֹוֶיךָ לֹא יֵבֹשׁוּ, יֵבֹשׁוּ הַבּוֹגְדִים רֵיקָם: דְּרָכֶיךָ יהוה הוֹדִיעֵנִי, אֹרְחוֹתֶיךָ לַמְּדֵנִי: הַדְרִיכֵנִי בַאֲמִתֶּךָ וְלַמְּדֵנִי, כִּי אַתָּה אֱלֹהֵי יִשְׁעִי, אוֹתְךָ קִוִּיתִי כָּל הַיּוֹם: זְכֹר רַחֲמֶיךָ יהוה וַחֲסָדֶיךָ, כִּי מֵעוֹלָם הֵמָּה: חַטֹּאות נְעוּרַי וּפְשָׁעַי אַל תִּזְכֹּר, כְּחַסְדְּךָ זְכָר לִי אַתָּה, לְמַעַן טוּבְךָ יהוה: טוֹב וְיָשָׁר יהוה, עַל כֵּן יוֹרֶה חַטָּאִים בַּדָּרֶךְ: יַדְרֵךְ עֲנָוִים בַּמִּשְׁפָּט, וִילַמֵּד עֲנָוִים דַּרְכּוֹ: כָּל אָרְחוֹת יהוה חֶסֶד וֶאֱמֶת לְנֹצְרֵי בְרִיתוֹ וְעֵדֹתָיו: לְמַעַן שִׁמְךָ יהוה, וְסָלַחְתָּ לַעֲוׂנִי כִּי רַב הוּא: מִי זֶה הָאִישׁ יְרֵא יהוה, יוֹרֶנּוּ בְּדֶרֶךְ יִבְחָר: נַפְשׁוֹ בְּטוֹב תָּלִין, וְזַרְעוֹ יִירַשׁ אָרֶץ: סוֹד יהוה לִירֵאָיו וּבְרִיתוֹ לְהוֹדִיעָם: עֵינַי תָּמִיד אֶל יהוה כִּי הוּא יוֹצִיא מֵרֶשֶׁת רַגְלָי: פְּנֵה אֵלַי וְחָנֵּנִי כִּי יָחִיד וְעָנִי אָנִי: צָרוֹת לְבָבִי הִרְחִיבוּ, מִמְּצוּקוֹתַי הוֹצִיאֵנִי: רְאֵה עָנְיִי וַעֲמָלִי, וְשָׂא לְכָל חַטֹּאותָי: רְאֵה אוֹיְבַי כִּי רָבּוּ וְשִׂנְאַת חָמָס שְׂנֵאוּנִי: שָׁמְרָה נַפְשִׁי וְהַצִּילֵנִי, אַל אֵבוֹשׁ כִּי חָסִיתִי בָךְ: תֹּם וָיֹשֶׁר יִצְּרוּנִי, כִּי קִוִּיתִיךָ: פְּדֵה אֱלֹהִים אֶת יִשְׂרָאֵל מִכֹּל צָרוֹתָיו: וְהוּא יִפְדֶּה אֶת יִשְׂרָאֵל, מִכָּל עֲוׂנוֹתָיו:\n\nיהוה אֱלֹהֵי יִשְׂרָאֵל, שׁוּב מֵחֲרוֹן אַפֶּךָ, וְהִנָּחֵם עַל הָרָעָה לְעַמֶּךָ.\n\nאָבִינוּ מַלְכֵּנוּ, אָבִינוּ אָתָּה. אָבִינוּ מַלְכֵּנוּ אֵין לָנוּ מֶלֶךְ אֶלָּא אָתָּה. אָבִינוּ מַלְכֵּנוּ רַחֵם עָלֵינוּ. אָבִינוּ מַלְכֵּנוּ חָנֵּנוּ וַעֲנֵנוּ כִּי אֵין בָּנוּ מַעֲשִׂים. עֲשֵׂה עִמָּנוּ חֶסֶד לְמַעַן שִׁמְךָ הַגָּדוֹל וְהושִׁיעֵנוּ. וַאֲנַחְנוּ לֹא נֵדַע מַה נַּעֲשֶׂה כִּי עָלֶיךָ עֵינֵינוּ:\n\nזְכֹר רַחֲמֶיךָ יהֹוָה וַחֲסָדֶיךָ, כִּי מֵעוֹלָם הֵמָּה: יְהִי חַסְדְּךָ יהוה עָלֵינוּ כַּאֲשֶׁר יִחַלְנוּ לָךְ: אַל תִּזְכָּר לָנוּ עֲוׂנוֹת רִאשׁוֹנִים, מַהֵר יְקַדְּמוּנוּ רַחֲמֶיךָ, כִּי דַלּוֹנוּ מְאד: עֶזְרֵנוּ בְּשֵׁם יהוה, עֹשֶׂה שָׁמַיִם וָאָרֶץ: חָנֵּנוּ יהוה חָנֵּנוּ, כִּי רַב שָׂבַעְנוּ בוּז: בְּרֹגֶז רַחֵם תִּזְכּוֹר: בְּרֹגֶז אַהֲבָה תִזְכֹּר, בְּרֹגֶז עֲקֵדָה תִזְכֹּר, בְּרֹגֶז תְּמִימוּת תִזְכֹּר. יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְּיוֹם קָרְאֵנוּ: כִּי הוּא יָדַע יִצְרֵנוּ, זָכוּר כִּי עָפָר אֲנָחְנוּ: עָזְרֵנוּ אֱלֹהֵי יִשְׁעֵנוּ עַל דְּבָר כְּבוֹד שְׁמֶךָ, וְהַצִּילֵנוּ וְכַפֵּר עַל חַטֹּאתֵינוּ לְמַעַן שְׁמֶךָ:","cond":["minchaTachanun"]},{"kind":"header","text":"יהי שם","cond":["noMinchaTachanun"]},{"kind":"special","text":"יְהִי שֵׁם יהוה מְבֹרָךְ, מֵעַתָּה וְעַד עוֹלָם: מִמִּזְרַח שֶׁמֶשׁ עַד מְבוֹאו, מְהֻלָּל שֵׁם יהוה: רָם עַל כָּל גּוֹיִם יהוה, עַל הַשָּׁמַיִם כְּבוֹדוֹ: יהוה אֲדוֹנֵנוּ, מָה אַדִּיר שִׁמְךָ בְּכָל הָאָרֶץ:","cond":["noMinchaTachanun"]},{"kind":"instruction","text":"קדיש תתקבל","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.\nתִּתְקַבַּל צְלוֹתָנָא וּבָעוּתָנָא עִם צְלוֹתְהוֹן וּבָעוּתְהוֹן דְּכָל בֵּית יִשְׂרָאֵל קֳדָם אֲבוּנָא דְבִשְׁמַיָּא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא, חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה וְשֵיזָבָא וּרְפוּאָה וּגְאֻלָּה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה, לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"header","text":"למנצח","cond":["noFri"]},{"kind":"text","text":"לַמְנַצֵּחַ בִּנְגִינֹת מִזְמוֹר שִׁיר: אֱלֹהִים יְחָנֵּנוּ וִיבָרְכֵנוּ, יָאֵר פָּנָיו אִתָּנוּ סֶלָה: לָדַעַת בָּאָרֶץ דַּרְכֶּךָ, בְּכָל-גּוֹיִם יְשׁוּעָתֶךָ: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: יִשְׂמְחוּ וִירַנְּנוּ לְאֻמִּים כִּי-תִשְׁפֹּט עַמִּים מִישֹׁר, וּלְאֻמִּים בָּאָרֶץ תַּנְחֵם סֶלָה: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: אֶרֶץ נָתְנָה יְבוּלָהּ, יְבָרְכֵנוּ אֱלֹהִים אֱלֹהֵינוּ: יְבָרְכֵנוּ אֱלֹהִים, וְיִירְאוּ אוֹתוֹ כָּל-אַפְסֵי-אָרֶץ:","cond":["noFri"]},{"kind":"header","text":"ה' מלך","cond":["fri"]},{"kind":"text","text":"יהוה מָלָךְ גֵּאוּת לָבֵשׁ, לָבֵשׁ יהוה עֹז הִתְאַזָּר, אַף-תִּכּוֹן תֵּבֵל בַּל-תִּמּוֹט: נָכוֹן כִּסְאֲךָ מֵאָז, מֵעוֹלָם אָתָּה: נָשְׂאוּ נְהָרוֹת, יהוה, נָשְׂאוּ נְהָרוֹת קוֹלָם, יִשְׂאוּ נְהָרוֹת דָכְיָם: מִקֹּלוֹת מַיִם רַבִּים, אַדִּירִים מִשְׁבְּרֵי-יָם, אַדִּיר בַּמָּרוֹם יהוה: עֵדֹתֶיךָ נֶאֶמְנוּ מְאֹד לְבֵיתְךָ נַאֲוָה-קֹדֶשׁ, יהוה, לְאֹרֶךְ יָמִים:","cond":["fri"]},{"kind":"header","text":"תפילה לעני","cond":["taanit"]},{"kind":"text","text":"תְּפִלָּה לְעָנִי כִי יַעֲטֹף, וְלִפְנֵי יהוה יִשְׁפֹּךְ שִׂיחוֹ: יהוה, שִׁמְעָה תְפִלָּתִי, וְשַׁוְעָתִי אֵלֶיךָ תָבוֹא: אַל תַּסְתֵּר פָּנֶיךָ מִמֶּנִּי, בְּיוֹם צַר לִי הַטֵּה אֵלַי אָזְנֶךָ, בְּיוֹם אֶקְרָא מַהֵר עֲנֵנִי: כִּי כָלוּ בְעָשָׁן יָמָי, וְעַצְמוֹתַי כְּמוֹ קֵד נִחָרוּ: הוּכָּה כָעֵשֶׂב וַיִּבַשׁ לִבִּי, כִּי שָׁכַחְתִּי מֵאֲכֹל לַחְמִי: מִקּוֹל אַנְחָתִי דָּבְקָה עַצְמִי לִבְשָׂרִי: דָּמִיתִי לִקְאַת מִדְבָּר, הָיִיתִי כְּכוֹס חֳרָבוֹת: שָׁקַדְתִּי וָאֶהְיֶה כְּצִפּוֹר בּוֹדֵד עַל גָּג: כָּל הַיּוֹם חֵרְפוּנִי אוֹיְבָי, מְהוֹלָלַי בִּי נִשְׁבָּעוּ: כִּי אֵפֶר כַּלֶּחֶם אָכָלְתִּי, וְשִׁקֻּוַי בִּבְכִי מָסָכְתִּי: מִפְּנֵי זַעַמְךָ וְקִצְפֶּךָ כִּי נְשָׂאתַנִי וַתַּשְׁלִיכֵנִי: יָמַי כְּצֵל נָטוּי, וַאֲנִי כָּעֵשֶׂב אִיבָשׁ: וְאַתָּה יהוה לְעוֹלָם תֵּשֵׁב, וְזִכְרְךָ לְדֹר וָדֹר: אַתָּה תָקוּם תְּרַחֵם צִיּוֹן, כִּי עֵת לְחֶנְנָהּ כִּי בָא מוֹעֵד: כִּי רָצוּ עֲבָדֶיךָ אֶת אֲבָנֶיהָ, וְאֶת עֲפָרָהּ יְחֹנֵנוּ: וְיִירְאוּ גוֹיִם אֶת שֵׁם יהוה, וְכָל מַלְכֵי הָאָרֶץ אֶת כְּבוֹדֶךָ: כִּי בָנָה יהוה צִיּוֹן, נִרְאָה בִּכְבוֹדוֹ: פָּנָה אֶל תְּפִלַּת הָעַרְעָר וְלֹא בָזָה אֶת תְּפִלָּתָם: תִּכָּתֶב זֹאת לְדוֹר אַחֲרוֹן, וְעַם נִבְרָא יְהַלֶּל יָהּ: כִּי הִשְׁקִיף מִמְּרוֹם קָדְשׁוֹ, יהוה מִשָּׁמַיִם אֶל אֶרֶץ הִבִּיט: לִשְׁמֹעַ אֶנְקַת אָסִיר, לְפַתֵּחַ בְּנֵי תְמוּתָה: לְסַפֵּר בְּצִיּוֹן שֵׁם יהוה, וּתְהִלָּתוֹ בִּירוּשָׁלִָם: בְּהִקָּבֵץ עַמִּים יַחְדָּו וּמַמְלָכוֹת לַעֲבֹד אֶת יהוה: עִנָּה בַדֶּרֶךְ כֹּחִי, קִצַּר יָמָי: אֹמַר אֵלִי אַל תַּעֲלֵנִי בַּחֲצִי יָמָי, בְּדוֹר דּוֹרִים שְׁנוֹתֶיךָ: לְפָנִים הָאָרֶץ יָסַדְתָּ, וּמַעֲשֵׂה יָדֶיךָ שָׁמָיִם: הֵמָּה יֹאבֵדוּ וְאַתָּה תַעֲמֹד, וְכֻלָּם כַּבֶּגֶד יִבְלוּ, כַּלְּבוּשׁ תַּחֲלִיפֵם וְיַחֲלֹפוּ: וְאַתָּה הוּא וּשְׁנוֹתֶיךָ לֹא יִתָּמּוּ: בְּנֵי עֲבָדֶיךָ יִשְׁכּוֹנוּ, וְזַרְעָם לְפָנֶיךָ יִכּוֹן:","cond":["taanit"]},{"kind":"instruction","text":"קדיש יהא שלמא","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא, חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה וְשֵיזָבָא וּרְפוּאָה וּגְאֻלָּה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה, לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"header","text":"עלינו לשבח","cond":[]},{"kind":"text","text":"עָלֵינוּ לְשַׁבֵּחַ לַאֲדוֹן הַכֹּל, לָתֵת גְּדֻלָּה לְיוֹצֵר בְּרֵאשִׁית, שֶׁלֹּא עָשָׂנוּ כְּגוֹיֵי הָאֲרָצוֹת וְלֹא שָׂמָנוּ כְּמִשְׁפְּחוֹת הָאֲדָמָה, שֶׁלֹּא שָׂם חֶלְקֵנוּ כָּהֶם וְגוֹרָלֵנוּ כְּכָל הֲמוֹנָם, שֶׁהֵם מִשְׁתַּחֲוִים לָהֶבֶל וָרִיק וּמִתְפַּלְּלִים אֶל אֵל לֹא יוֹשִׁיעַ, וַאֲנַחְנוּ מִשְׁתַּחֲוִים לִפְנֵי מֶלֶךְ מַלְכֵי הַמְּלָכִים הַקָּדוֹשׁ בָּרוּךְ הוּא, שֶׁהוּא נוֹטֶה שָׁמַיִם וְיוֹסֵד אָרֶץ, וּמוֹשַׁב יְקָרוֹ בַּשָּׁמַיִם מִמַּעַל, וּשְׁכִינַת עֻזּוֹ בְּגָבְהֵי מְרוֹמִים. הוּא אֱלֹהֵינוּ וְאֵין עוֹד אַחֵר. אֱמֶת מַלְכֵּנוּ וְאֶפֶס זוּלָתוֹ, כַּכָּתוּב בַּתּוֹרָה: וְיָדַעְתָּ הַיּוֹם וַהֲשֵׁבוֹתָ אֶל לְבָבֶךָ כִּי יהוה הוּא הָאֱלֹהִים בַּשָּׁמַיִם מִמַּעַל וְעַל הָאָרֶץ מִתָּחַת, אֵין עוֹד:","cond":[]},{"kind":"text","text":"עַל כֵּן נְקַוֶּה לָךְ יהוה אֱלֹהֵינוּ לִרְאוֹת מְהֵרָה בְּתִפְאֶרֶת עֻזָּךְ לְהַעֲבִיר גִּלּוּלִים מִן הָאָרֶץ וְהָאֱלִילִים כָּרוֹת יִכָּרֵתוּן, לְתַקֵּן עוֹלָם בְּמַלְכוּת שַׁדַּי, וְכָל בְּנֵי בָשָׂר יִקְרְאוּ בִשְׁמֶךָ לְהַפְנוֹת אֵלֶיךָ כָּל רִשְׁעֵי אָרֶץ. יַכִּירוּ וְיֵדְעוּ כָּל יוֹשְׁבֵי תֵבֵל כִּי לְךָ תִכְרַע כָּל בֶּרֶךְ, תִּשָּׁבַע כָּל לָשׁוֹן. לְפָנֶיךָ יהוה אֱלֹהֵינוּ יִכְרְעוּ וְיִפֹּלוּ וְלִכְבוֹד שִׁמְךָ יְקָר יִתֵּנוּ, וִיקַבְּלוּ כֻלָּם אֶת עוֹל מַלְכוּתֶךָ, וְתִמְלוֹךְ עֲלֵיהֶם מְהֵרָה לְעוֹלָם וָעֶד. כִּי הַמַּלְכוּת שֶׁלְּךָ הִיא, וּלְעוֹלְמֵי עַד תִּמְלוֹךְ בְּכָבוד, כַּכָּתוּב בְּתוֹרָתָךְ: יהוה יִמְלֹךְ לְעֹלָם וָעֶד: וְנֶאֱמַר: וְהָיָה יהוה לְמֶלֶךְ עַל כָּל הָאָרֶץ, בַּיּום הַהוּא יִהְיֶה יהוה אֶחָד וּשְׁמוֹ אֶחָד:","cond":[]},{"kind":"header","text":"השלמת שחרית","cond":["tishaaBeav"]},{"kind":"header","text":"שיר של יום","cond":["tishaaBeav"]},{"kind":"instruction","text":"שיר של יום","cond":["tishaaBeav"]},{"kind":"text","text":"תְּפִלָּה לְדָוִד, הַטֵּה יהוה אָזְנְךָ עֲנֵנִי, כִּי עָנִי וְאֶבְיוֹן אָנִי: שָׁמְרָה נַפְשִׁי כִּי חָסִיד אָנִי, הוֹשַׁע עַבְדְּךָ, אַתָּה אֱלֹהַי, הַבּוֹטֵחַ אֵלֶיךָ: חָנֵּנִי אֲדֹנָי, כִּי אֵלֶיךָ אֶקְרָא כָּל הַיּוֹם: שַׂמֵּחַ נֶפֶשׁ עַבְדֶּךָ, כִּי אֵלֶיךָ אֲדֹנָי נַפְשִׁי אֶשָּׂא: כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ: הַאֲזִינָה יהוה תְּפִלָּתִי וְהַקְשִׁיבָה בְּקוֹל תַּחֲנוּנוֹתָי: בְּיוֹם צָרָתִי אֶקְרָאֶךָּ כִּי תַעֲנֵנִי: אֵין כָּמוֹךָ בָאֱלֹהִים, אֲדֹנָי, וְאֵין כְּמַעֲשֶׂיךָ: כָּל גּוֹיִם אֲשֶׁר עָשִׂיתָ יָבוֹאוּ וְיִשְׁתַּחֲווּ לְפָנֶיךָ, אֲדֹנָי, וִיכַבְּדוּ לִשְׁמֶךָ: כִּי גָדוֹל אַתָּה וְעֹשֵׂה נִפְלָאוֹת, אַתָּה אֱלֹהִים לְבַדֶּךָ: הוֹרֵנִי יהוה דַּרְכֶּךָ, אֲהַלֵּךְ בַּאֲמִתֶּךָ, יַחֵד לְבָבִי לְיִרְאָה שְׁמֶךָ: אוֹדְךָ אֲדֹנָי אֱלֹהַי בְּכָל לְבָבִי, וַאֲכַבְּדָה שִׁמְךָ לְעוֹלָם: כִּי חַסְדְּךָ גָּדוֹל עָלָי, וְהִצַּלְתָּ נַפְשִׁי מִשְּׁאוֹל תַּחְתִּיָּה: אֱלֹהִים, זֵדִים קָמוּ עָלַי, וַעֲדַת עָרִיצִים בִּקְשׁוּ נַפְשִׁי, וְלֹא שָׂמוּךָ לְנֶגְדָּם: וְאַתָּה אֲדֹנָי אֵל רַחוּם וְחַנּוּן, אֶרֶךְ אַפַּיִם וְרַב חֶסֶד וֶאֱמֶת: פְּנֵה אֵלַי וְחָנֵּנִי, תְּנָה עֻזְּךָ לְעַבְדֶּךָ, וְהוֹשִׁיעָה לְבֶן אֲמָתֶךָ: עֲשֵׂה עִמִּי אוֹת לְטוֹבָה, וְיִרְאוּ שֹׂנְאַי וְיֵבֹשׁוּ, כִּי אַתָּה יהוה עֲזַרְתַּנִי וְנִחַמְתָּנִי:","cond":["tishaaBeav","shacharitTachanun"]},{"kind":"text","text":"בֵּית יַעֲקֹב, לְכוּ וְנֵלְכָה בְּאוֹר יהוה: כִּי כָּל הָעַמִּים יֵלְכוּ אִישׁ בְּשֵׁם אֱלֹהָיו, וַאֲנַחְנוּ נֵלֵךְ בְּשֵׁם יהוה אֱלֹהֵינוּ לְעוֹלָם וָעֶד: יְהִי יהוה אֱלֹהֵינוּ עִמָּנוּ כַּאֲשֶׁר הָיָה עִם אבוֹתֵינוּ, אַל יַעַזְבֵנוּ וְאַל יִטְּשֵׁנוּ: לְהַטּות לְבָבֵנוּ אֵלָיו, לָלֶכֶת בְּכָל דְּרָכָיו וְלִשְׁמֹר מִצְוׂתָיו וְחֻקָּיו וּמִשְׁפָּטָיו אֲשֶׁר צִוָּה אֶת אֲבֹתֵינוּ: וְיִהְיוּ דְבָרַי אֵלֶּה אֲשֶׁר הִתְחַנַּנְתִּי לִפְנֵי יהוה קְרֹבִים אֶל יהוה אֱלֹהֵינוּ יוֹמָם וָלָיְלָה, לַעֲשׂוֹת מִשְׁפַּט עַבְדּוֹ וּמִשְׁפַּט עַמּוֹ יִשְׂרָאֵל דְּבַר יוֹם בְּיוֹמוֹ: לְמַעַן דַּעַת כָּל עַמֵּי הָאָרֶץ כִּי יהוה הוּא הָאֱלֹהִים, אֵין עוד:\n\nשִׁיר הַמַּעֲלוֹת לְדָוִד, לוּלֵי יהוה שֶׁהָיָה לָנוּ יֹאמַר נָא יִשְׂרָאֵל: לוּלֵי יהוה שֶׁהָיָה לָנוּ בְּקוּם עָלֵינוּ אָדָם: אֲזַי חַיִּים בְּלָעוּנוּ בַּחֲרוֹת אַפָּם בָּנוּ: אֲזַי הַמַּיִם שְׁטָפוּנוּ נַחְלָה עָבַר עַל נַפְשֵׁנוּ: אֲזַי עָבַר עַל נַפְשֵׁנוּ הַמַּיִם הַזֵּידוֹנִים: בָּרוּךְ יהוה שֶׁלֹּא נְתָנָנוּ טֶרֶף לְשִׁנֵּיהֶם: נַפְשֵׁנוּ כְּצִפּוֹר נִמְלְטָה מִפַּח יוֹקְשִׁים, הַפַּח נִשְׁבָּר וַאֲנַחְנוּ נִמְלָטְנוּ: עֶזְרֵנוּ בְּשֵׁם יהוה, עֹשֵׂה שָׁמַיִם וָאָרֶץ:","cond":["tishaaBeav"]},{"kind":"instruction","text":"כשמזכיר \"היום יום פלוני בשבת\" טוב לכון שהוא מקיים מצוות עשה מן התורה של זכירת השבת.","cond":["tishaaBeav"]},{"kind":"text","text":"הַיּוֹם יוֹם אֶחָד בַּשַּׁבָּת, הַשִּׁיר שֶׁהָיוּ הַלְוִיִּם אוֹמְרִים עַל הַדּוּכָן:","cond":["tishaaBeav","sun","shirOpenD"]},{"kind":"text","text":"הַיּוֹם יוֹם אֶחָד בַּשַּׁבָּת.","cond":["tishaaBeav","sun","ShirOpenND"]},{"kind":"text","text":"לְדָוִד מִזְמוֹר, לַיהוה הָאָרֶץ וּמְלוֹאָהּ, תֵּבֵל וְיֹשְׁבֵי בָהּ: כִּי הוּא עַל יַמִּים יְסָדָהּ, וְעַל נְהָרוֹת יְכוֹנְנֶהָ: מִי יַעֲלֶה בְהַר יהוה, וּמִי יָקוּם בִּמְקוֹם קָדְשׁוֹ: נְקִי כַפַּיִם וּבַר לֵבָב, אֲשֶׁר לֹא נָשָׂא לַשָּׁוְא נַפְשִׁי וְלֹא נִשְׁבַּע לְמִרְמָה: יִשָּׂא בְרָכָה מֵאֵת יהוה, וּצְדָקָה מֵאֱלֹהֵי יִשְׁעוֹ: זֶה דּוֹר דֹּרְשָׁיו, מְבַקְשֵׁי פָנֶיךָ יַעֲקֹב סֶלָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וְהִנָּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבוֹא מֶלֶךְ הַכָּבוֹד: מִי זֶה מֶלֶךְ הַכָּבוֹד, יהוה עִזּוּז וְגִבּוֹר, יהוה גִּבּוֹר מִלְחָמָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבֹא מֶלֶךְ הַכָּבוֹד: מִי הוּא זֶה מֶלֶךְ הַכָּבוֹד, יהוה צְבָאוֹת הוּא מֶלֶךְ הַכָּבוֹד סֶלָה:","cond":["tishaaBeav","sun"]},{"kind":"text","text":"הַיּוֹם יוֹם שֵׁנִי בַשַּׁבָּת, הַשִּׁיר שֶׁהָיוּ הַלְוִיִּם אוֹמְרִים עַל הַדּוּכָן:","cond":["tishaaBeav","mon","shirOpenD"]},{"kind":"text","text":"הַיּוֹם יוֹם שֵׁנִי בַשַּׁבָּת.","cond":["tishaaBeav","mon","ShirOpenND"]},{"kind":"text","text":"שִׁיר מִזְמוֹר לִבְנֵי קֹרַח: גָּדוֹל יהוה וּמְהֻלָּל מְאֹד בְּעִיר אֱלֹהֵינוּ הַר קָדְשׁוֹ: יְפֵה נוֹף, מְשׂוֹשׂ כָּל הָאָרֶץ, הַר צִיּוֹן יַרְכְּתֵי צָפוֹן קִרְיַת מֶלֶךְ רָב: אֱלֹהִים בְּאַרְמְנוֹתֶיהָ נוֹדַע לְמִשְׂגָּב: כִּי הִנֵּה הַמְּלָכִים נוֹעֲדוּ עָבְרוּ יַחְדָּו: הֵמָּה רָאוּ כֵּן תָּמָהוּ, נִבְהֲלוּ נֶחְפָּזוּ: רְעָדָה אֲחָזָתַם שָׁם, חִיל כַּיּוֹלֵדָה: בְּרוּחַ קָדִים תְּשַׁבֵּר אֳנִיּוֹת תַּרְשִׁישׁ: כַּאֲשֶׁר שָׁמַעְנוּ כֵּן רָאִינוּ בְּעִיר יהוה צְבָאוֹת בְּעִיר אֱלֹהֵינוּ, אֱלֹהִים יְכוֹנְנֶהָ עַד עוֹלָם סֶלָה: דִּמִּינוּ אֱלֹהִים חַסְדֶּךָ בְּקֶרֶב הֵיכָלֶךָ: כְּשִׁמְךָ אֱלֹהִים כֵּן תְּהִלָּתְךָ עַל קַצְוֵי אֶרֶץ, צֶדֶק מָלְאָה יְמִינֶךָ: יִשְׂמַח הַר צִיּוֹן, תָּגֵלְנָה בְּנוֹת יְהוּדָה, לְמַעַן מִשְׁפָּטֶיךָ: סֹבּוּ צִיּוֹן וְהַקִּיפוּהָ, סִפְרוּ מִגְדָּלֶיהָ: שִׁיתוּ לִבְּכֶם לְחֵילָה, פַּסְּגוּ אַרְמְנוֹתֶיהָ, לְמַעַן תְּסַפְּרוּ לְדוֹר אַחֲרוֹן: כִּי זֶה אֱלֹהִים אֱלֹהֵינוּ עוֹלָם וָעֶד, הוּא יְנַהֲגֵנוּ עַל מוּת:","cond":["tishaaBeav","mon"]},{"kind":"text","text":"הַיּוֹם יוֹם שְׁלִישִׁי בַשַּׁבָּת, הַשִּׁיר שֶׁהָיוּ הַלְוִיִּם אוֹמְרִים עַל הַדּוּכָן:","cond":["tishaaBeav","tue","shirOpenD"]},{"kind":"text","text":"הַיּוֹם יוֹם שְׁלִישִׁי בַשַּׁבָּת.","cond":["tishaaBeav","tue","ShirOpenND"]},{"kind":"text","text":"מִזְמוֹר לְאָסָף, אֱלֹהִים נִצָּב בַּעֲדַת אֵל, בְּקֶרֶב אֱלֹהִים יִשְׁפֹּט: עַד מָתַי תִּשְׁפְּטוּ עָוֶל וּפְנֵי רְשָׁעִים תִּשְׂאוּ סֶלָה: שִׁפְטוּ דַל וְיָתוֹם, עָנִי וָרָשׁ הַצְדִּיקוּ: פַּלְּטוּ דַל וְאֶבְיוֹן, מִיַּד רְשָׁעִים הַצִּילוּ: לֹא יָדְעוּ וְלֹא יָבִינוּ, בַּחֲשֵׁכָה יִתְהַלָּכוּ, יִמּוֹטוּ כָּל מוֹסְדֵי אָרֶץ: אֲנִי אָמַרְתִּי אֱלֹהִים אַתֶּם וּבְנֵי עֶלְיוֹן כֻּלְּכֶם: אָכֵן כְּאָדָם תְּמוּתוּן וּכְאַחַד הַשָּׂרִים תִּפֹּלוּ: קוּמָה אֱלֹהִים שָׁפְטָה הָאָרֶץ, כִּי אַתָּה תִנְחַל בְּכָל הַגּוֹיִם:","cond":["tishaaBeav","tue"]},{"kind":"text","text":"הַיּוֹם יוֹם רְבִיעִי בַשַּׁבָּת, הַשִּׁיר שֶׁהָיוּ הַלְוִיִּם אוֹמְרִים עַל הַדּוּכָן:","cond":["tishaaBeav","wed","shirOpenD"]},{"kind":"text","text":"הַיּוֹם יוֹם רְבִיעִי בַשַּׁבָּת.","cond":["tishaaBeav","wed","ShirOpenND"]},{"kind":"text","text":"אֵל נְקָמוֹת יהוה, אֵל נְקָמוֹת הוֹפִיעַ: הִנָּשֵׂא שֹׁפֵט הָאָרֶץ, הָשֵׁב גְּמוּל עַל גֵּאִים: עַד מָתַי רְשָׁעִים, יהוה, עַד מָתַי רְשָׁעִים יַעֲלֹזוּ: יַבִּיעוּ יְדַבְּרוּ עָתָק, יִתְאַמְּרוּ כָּל פֹעֲלֵי אָוֶן: עַמְּךָ יהוה יְדַכְּאוּ, וְנַחֲלָתְךָ יְעַנּוּ: אַלְמָנָה וְגֵר יַהֲרֹגוּ, וִיתוֹמִים יְרַצֵּחוּ: וַיֹּאמְרוּ לֹא יִרְאֶה יָהּ, וְלֹא יָבִין אֱלֹהֵי יַעֲקֹב: בִּינוּ בֹּעֲרִים בָּעָם, וּכְסִילִים מָתַי תַּשְׂכִּילוּ: הַנֹּטַע אֹזֶן הֲלֹא יִשְׁמָע, אִם יֹצֵר עַיִן הֲלֹא יַבִּיט: הֲיֹסֵר גּוֹיִם הֲלֹא יוֹכִיחַ, הַמְלַמֵּד אָדָם דָּעַת: יהוה יֹדֵעַ מַחְשְׁבוֹת אָדָם כִּי הֵמָּה הָבֶל: אַשְׁרֵי הַגֶּבֶר אֲשֶׁר תְּיַסְּרֶנּוּ יָּהּ, וּמִתּוֹרָתְךָ תְלַמְּדֶנּוּ: לְהַשְׁקִיט לוֹ מִימֵי רָע, עַד יִכָּרֶה לָרָשָׁע שָׁחַת: כִּי לֹא יִטֹּשׁ יהוה עַמּוֹ, וְנַחֲלָתוֹ לֹא יַעֲזֹב: כִּי עַד צֶדֶק יָשׁוּב מִשְׁפָּט, וְאַחֲרָיו כָּל יִשְׁרֵי לֵב: מִי יָקוּם לִי עִם מְרֵעִים, מִי יִתְיַצֵּב לִי עִם פֹּעֲלֵי אָוֶן: לוּלֵי יהוה עֶזְרָתָה לִּי, כִּמְעַט שָׁכְנָה דוּמָה נַפְשִׁי: אִם אָמַרְתִּי מָטָה רַגְלִי, חַסְדְּךָ יהוה יִסְעָדֵנִי: בְּרֹב שַׂרְעַפַּי בְּקִרְבִּי, תַּנְחוּמֶיךָ יְשַׁעַשְׁעוּ נַפְשִׁי: הַיְחָבְרְךָ כִּסֵּא הַוּוֹת, יֹצֵר עָמָל עֲלֵי חֹק: יָגוֹדּוּ עַל נֶפֶשׁ צַדִּיק, וְדָם נָקִי יַרְשִׁיעוּ: וַיְהִי יהוה לִי לְמִשְׂגָּב, וֵאלֹהַי לְצוּר מַחְסִי: וַיָּשֶׁב עֲלֵיהֶם אֶת אוֹנָם וּבְרָעָתָם יַצְמִיתֵם, יַצְמִיתֵם יהוה אֱלֹהֵינוּ:","cond":["tishaaBeav","wed"]},{"kind":"text","text":"הַיּוֹם יוֹם חֲמִישִׁי בַשַּׁבָּת, הַשִּׁיר שֶׁהָיוּ הַלְוִיִּם אוֹמְרִים עַל הַדּוּכָן:","cond":["tishaaBeav","thu","shirOpenD"]},{"kind":"text","text":"הַיּוֹם יוֹם חֲמִישִׁי בַשַּׁבָּת.","cond":["tishaaBeav","thu","ShirOpenND"]},{"kind":"text","text":"לַמְנַצֵּחַ עַל הַגִּתִּית לְאָסָף: הַרְנִינוּ לֵאלֹהִים עֻזֵּנוּ, הָרִיעוּ לֵאלֹהֵי יַעֲקֹב: שְׂאוּ זִמְרָה וּתְנוּ תֹף, כִּנּוֹר נָעִים עִם נָבֶל: תִּקְעוּ בַחֹדֶשׁ שׁוֹפָר, בַּכֵּסֶה לְיוֹם חַגֵּנוּ: כִּי חֹק לְיִשְׂרָאֵל הוּא, מִשְׁפָּט לֵאלֹהֵי יַעֲקֹב: עֵדוּת בִּיהוֹסֵף שָׂמוֹ בְּצֵאתוֹ עַל אֶרֶץ מִצְרָיִם, שְׂפַת לֹא יָדַעְתִּי אֶשְׁמָע: הֲסִירוֹתִי מִסֵּבֶל שִׁכְמוֹ, כַּפָּיו מִדּוּד תַּעֲבֹרְנָה: בַּצָּרָה קָרָאתָ וָאֲחַלְּצֶךָּ, אֶעֶנְךָ בְּסֵתֶר רַעַם, אֶבְחָנְךָ עַל מֵי מְרִיבָה סֶלָה: שְׁמַע עַמִּי וְאָעִידָה בָּךְ, יִשְׂרָאֵל אִם תִּשְׁמַע לִי: לֹא יִהְיֶה בְךָ אֵל זָר, וְלֹא תִשְׁתַּחֲוֶה לְאֵל נֵכָר: אָנֹכִי יהוה אֱלֹהֶיךָ הַמַּעַלְךָ מֵאֶרֶץ מִצְרָיִם, הַרְחֶב פִּיךָ וַאֲמַלְאֵהוּ: וְלֹא שָׁמַע עַמִּי לְקוֹלִי, וְיִשְׂרָאֵל לֹא אָבָה לִי: וָאֲשַׁלְּחֵהוּ בִּשְׁרִירוּת לִבָּם, יֵלְכוּ בְּמוֹעֲצוֹתֵיהֶם: לוּ עַמִּי שֹׁמֵעַ לִי, יִשְׂרָאֵל בִּדְרָכַי יְהַלֵּכוּ: כִּמְעַט אוֹיְבֵיהֶם אַכְנִיעַ, וְעַל צָרֵיהֶם אָשִׁיב יָדִי: מְשַׂנְאֵי יהוה יְכַחֲשׁוּ לוֹ, וִיהִי עִתָּם לְעוֹלָם: וַיַּאֲכִילֵהוּ מֵחֵלֶב חִטָּה, וּמִצּוּר, דְּבַשׁ אַשְׂבִּיעֶךָ:","cond":["tishaaBeav","thu"]},{"kind":"text","text":"הַיּוֹם יוֹם הַשִּׁשִּׁי בַשַּׁבָּת, הַשִּׁיר שֶׁהָיוּ הַלְוִיִּם אוֹמְרִים עַל הַדּוּכָן:","cond":["tishaaBeav","fri","shirOpenD"]},{"kind":"text","text":"הַיּוֹם יוֹם הַשִּׁשִּׁי בַשַּׁבָּת.","cond":["tishaaBeav","fri","ShirOpenND"]},{"kind":"text","text":"יהוה מָלָךְ גֵּאוּת לָבֵשׁ, לָבֵשׁ יהוה עֹז הִתְאַזָּר, אַף תִּכּוֹן תֵּבֵל בַּל תִּמּוֹט: נָכוֹן כִּסְאֲךָ מֵאָז, מֵעוֹלָם אָתָּה: נָשְׂאוּ נְהָרוֹת, יהוה, נָשְׂאוּ נְהָרוֹת קוֹלָם, יִשְׂאוּ נְהָרוֹת דָכְיָם: מִקֹּלוֹת מַיִם רַבִּים, אַדִּירִים מִשְׁבְּרֵי יָם, אַדִּיר בַּמָּרוֹם יהוה: עֵדֹתֶיךָ נֶאֶמְנוּ מְאֹד לְבֵיתְךָ נַאֲוָה קֹדֶשׁ, יהוה, לְאֹרֶךְ יָמִים:","cond":["tishaaBeav","fri"]},{"kind":"instruction","text":"בבית האבל אומרים מזמור זה:","cond":["tishaaBeav"]},{"kind":"text","text":"לַמְנַצֵּחַ לִבְנֵי קֹרַח מִזְמוֹר: שִׁמְעוּ זֹאת כָּל הָעַמִּים, הַאֲזִינוּ כָּל יֹשְׁבֵי חָלֶד: גַּם בְּנֵי אָדָם, גַּם בְּנֵי אִישׁ, יַחַד עָשִׁיר וְאֶבְיוֹן: פִּי יְדַבֵּר חָכְמוֹת, וְהָגוּת לִבִּי תְבוּנוֹת: אַטֶּה לְמָשָׁל אָזְנִי, אֶפְתַּח בְּכִנּוֹר חִידָתִי: לָמָּה אִירָא בִּימֵי רָע, עֲוׂן עֲקֵבַי יְסוּבֵּנִי: הַבֹּטְחִים עַל חֵילָם, וּבְרֹב עָשְׁרָם יִתְהַלָּלוּ: אָח לֹא פָדֹה יִפְדֶּה אִישׁ, לֹא יִתֵּן לֵאלֹהִים כָּפְרוֹ: וְיֵקַר פִּדְיוֹן נַפְשָׁם, וְחָדַל לְעוֹלָם: וִיחִי עוֹד לָנֶצַח, לֹא יִרְאֶה הַשָּׁחַת: כִּי יִרְאֶה חֲכָמִים יָמוּתוּ, יַחַד כְּסִיל וָבַעַר יֹאבֵדוּ, וְעָזְבוּ לַאֲחֵרִים חֵילָם: קִרְבָּם בָּתֵּימוֹ לְעוֹלָם, מִשְׁכְּנֹתָם לְדֹר וָדֹר, קָרְאוּ בִשְׁמוֹתָם עֲלֵי אֲדָמוֹת: וְאָדָם בִּיקָר בַּל יָלִין, נִמְשַׁל כַּבְּהֵמוֹת נִדְמוּ: זֶה דַרְכָּם כֵּסֶל לָמוֹ, וְאַחֲרֵיהֶם בְּפִיהֶם יִרְצוּ סֶלָה: כַּצֹּאן לִשְׁאוֹל שַׁתּוּ מָוֶת יִרְעֵם, וַיִּרְדּוּ בָם יְשָׁרִים לַבֹּקֶר, וְצוּרָם לְבַלּוֹת שְׁאוֹל מִזְּבֻל לוֹ: אַךְ אֱלֹהִים יִפְדֶּה נַפְשִׁי מִיַּד שְׁאוֹל, כִּי יִקָּחֵנִי סֶלָה: אַל תִּירָא כִּי יַעֲשִׁר אִישׁ, כִּי יִרְבֶּה כְּבוֹד בֵּיתוֹ: כִּי לֹא בְמוֹתוֹ יִקַּח הַכֹּל, לֹא יֵרֵד אַחֲרָיו כְּבוֹדוֹ: כִּי נַפְשׁוֹ בְּחַיָּיו יְבָרֵךְ, וְיוֹדֻךָ כִּי תֵיטִיב לָךְ: תָּבוֹא עַד דּוֹר אֲבוֹתָיו, עַד נֵצַח לֹא יִרְאוּ אוֹר: אָדָם בִּיקָר וְלֹא יָבִין נִמְשַׁל כַּבְּהֵמוֹת נִדְמוּ:","cond":["tishaaBeav"]},{"kind":"header","text":"הושיענו","cond":["tishaaBeav"]},{"kind":"instruction","text":"בכל יום אחרי שיר של יום אומרים:","cond":["tishaaBeav"]},{"kind":"text","text":"הוֹשִׁיעֵנוּ יהוה אֱלֹהֵינוּ וְקַבְּצֵנוּ מִן הַגּוֹיִם, לְהֹדוֹת לְשֵׁם קָדְשֶׁךָ לְהִשְׁתַּבֵּחַ בִּתְהִלָּתֶךָ: בָּרוּךְ יהוה אֱלֹהֵי יִשְׂרָאֵל מִן הָעוֹלָם וְעַד הָעוֹלָם, וְאָמַר כָּל הָעָם אָמֵן הַלְלוּיָהּ: בָּרוּךְ יהוה מִצִּיּוֹן, שֹׁכֵן יְרוּשָׁלִָם הַלְלוּיָהּ: בָּרוּךְ יהוה אֱלֹהִים אֱלֹהֵי יִשְׂרָאֵל, עֹשֵׂה נִפְלָאוֹת לְבַדּוֹ: וּבָרוּךְ שֵׁם כְּבוֹדוֹ לְעוֹלָם, וְיִמָּלֵא כְבוֹדוֹ אֶת כָּל הָאָרֶץ, אָמֵן וְאָמֵן:","cond":["tishaaBeav"]},{"kind":"special","text":"מזמור לשבעה עשר בתמוז:","cond":["tishaaBeav","17tammuz"]},{"kind":"text","text":"מִזְמוֹר לְאָסָף, אֱלֹהִים, בָּאוּ גוֹיִם בְּנַחֲלָתֶךָ טִמְּאוּ אֶת הֵיכַל קָדְשֶׁךָ, שָׂמוּ אֶת יְרוּשָׁלַיִם לְעִיִּים: נָתְנוּ אֶת נִבְלַת עֲבָדֶיךָ מַאֲכָל לְעוֹף הַשָּׁמָיִם, בְּשַׂר חֲסִידֶיךָ לְחַיְתוֹ אָרֶץ: שָׁפְכוּ דָמָם כַּמַּיִם סְבִיבוֹת יְרוּשָׁלִָם וְאֵין קוֹבֵר: הָיִינוּ חֶרְפָּה לִשְׁכֵנֵינוּ, לַעַג וָקֶלֶס לִסְבִיבוֹתֵינוּ: עַד מָה יהוה תֶּאֱנַף לָנֶצַח, תִּבְעַר כְּמוֹ אֵשׁ קִנְאָתֶךָ: שְׁפֹךְ חֲמָתְךָ אֶל הַגּוֹיִם אֲשֶׁר לֹא יְדָעוּךָ, וְעַל מַמְלָכוֹת אֲשֶׁר בְּשִׁמְךָ לֹא קָרָאוּ: כִּי אָכַל אֶת יַעֲקֹב וְאֶת נָוֵהוּ הֵשַׁמּוּ: אַל תִּזְכָּר לָנוּ עֲוׂנֹת רִאשֹׁנִים, מַהֵר יְקַדְּמוּנוּ רַחֲמֶיךָ כִּי דַלּוֹנוּ מְאֹד: עָזְרֵנוּ אֱלֹהֵי יִשְׁעֵנוּ עַל דְּבַר כְּבוֹד שְׁמֶךָ, וְהַצִּילֵנוּ וְכַפֵּר עַל חַטֹּאתֵינוּ לְמַעַן שְׁמֶךָ: לָמָּה יֹאמְרוּ הַגּוֹיִם אַיֵּה אֱלֹהֵיהֶם, יִוָּדַע בַּגּוֹיִם לְעֵינֵינוּ נִקְמַת דַּם עֲבָדֶיךָ הַשָּׁפוּךְ: תָּבוֹא לְפָנֶיךָ אֶנְקַת אָסִיר כְּגֹדֶל זְרוֹעֲךָ הוֹתֵר בְּנֵי תְמוּתָה: וְהָשֵׁב לִשְׁכֵנֵינוּ שִׁבְעָתַיִם אֶל חֵיקָם חֶרְפָּתָם אֲשֶׁר חֵרְפוּךָ אֲדֹנָי: וַאֲנַחְנוּ עַמְּךָ וְצֹאן מַרְעִיתֶךָ נוֹדֶה לְּךָ לְעוֹלָם, לְדֹר וָדֹר נְסַפֵּר תְּהִלָּתֶךָ:","cond":["tishaaBeav","17tammuz"]},{"kind":"special","text":"מזמור למחרת יום הכיפורים:","cond":["tishaaBeav","11tishrei"]},{"kind":"text","text":"לַמְנַצֵּחַ לִבְנֵי-קֹרַח מִזְמוֹר: רָצִיתָ יהוה אַרְצֶךָ, שַׁבְתָּ שְׁבִית יַעֲקֹב: נָשָׂאתָ עֲוׂן עַמֶּךָ, כִּסִּיתָ כָל-חַטָּאתָם סֶלָה: אָסַפְתָּ כָל-עֶבְרָתֶךָ, הֱשִׁיבוֹתָ מֵחֲרוֹן אַפֶּךָ: שׁוּבֵנוּ אֱלֹהֵי יִשְׁעֵנוּ, וְהָפֵר כַּעַסְךָ עִמָּנוּ: הַלְעוֹלָם תֶּאֱנַף-בָּנוּ, תִּמְשֹׁךְ אַפְּךָ לְדֹר וָדֹר: הֲלֹא-אַתָּה תָּשׁוּב תְּחַיֵּנוּ, וְעַמְּךָ יִשְׂמְחוּ-בָךְ: הַרְאֵנוּ יהוה חַסְדֶּךָ, וְיֶשְׁעֲךָ תִּתֶּן-לָנוּ: אֶשְׁמְעָה מַה-יְדַבֵּר הָאֵל יהוה, כִּי יְדַבֵּר שָׁלוֹם אֶל-עַמּוֹ וְאֶל-חֲסִידָיו, וְאַל-יָשׁוּבוּ לְכִסְלָה: אַךְ קָרוֹב לִירֵאָיו יִשְׁעוֹ, לִשְׁכֹּן כָּבוֹד בְּאַרְצֵנוּ: חֶסֶד-וֶאֱמֶת נִפְגָּשׁוּ, צֶדֶק וְשָׁלוֹם נָשָׁקוּ: אֱמֶת מֵאֶרֶץ תִּצְמָח, וְצֶדֶק מִשָּׁמַיִם נִשְׁקָף: גַּם-יהוה יִתֵּן הַטּוֹב, וְאַרְצֵנוּ תִּתֵּן יְבוּלָהּ: צֶדֶק לְפָנָיו יְהַלֵּךְ, וְיָשֵׂם לְדֶרֶךְ פְּעָמָיו:","cond":["tishaaBeav","11tishrei"]},{"kind":"special","text":"מזמור לצום גדליה ולעשרה בטבת:","cond":["tishaaBeav","gedalya"]},{"kind":"text","text":"שִׁיר מִזְמוֹר לְאָסָף: אֱלֹהִים אַל דֳּמִי לָךְ, אַל תֶּחֱרַשׁ וְאַל תִּשְׁקֹט אֵל: כִּי הִנֵּה אוֹיְבֶיךָ יֶהֱמָיוּן, וּמְשַׂנְאֶיךָ נָשְׂאוּ רֹאשׁ: עַל עַמְּךָ יַעֲרִימוּ סוֹד, וְיִתְיָעֲצוּ עַל צְפוּנֶיךָ: אָמְרוּ לְכוּ וְנַכְחִידֵם מִגּוֹי, וְלֹא יִזָּכֵר שֵׁם יִשְׂרָאֵל עוֹד: כִּי נוֹעֲצוּ לֵב יַחְדָּו, עָלֶיךָ בְּרִית יִכְרֹתוּ: אָהֳלֵי אֱדוֹם וְיִשְׁמְעֵאלִים, מוֹאָב וְהַגְרִים: גְּבָל וְעַמּוֹן וַעֲמָלֵק, פְּלֶשֶׁת עִם יֹשְׁבֵי צוֹר: גַּם אַשּׁוּר נִלְוָה עִמָּם, הָיוּ זְרוֹעַ לִבְנֵי לוֹט סֶלָה: עֲשֵׂה לָהֶם כְּמִדְיָן, כְּסִיסְרָא כְיָבִין בְּנַחַל קִישׁוֹן: נִשְׁמְדוּ בְעֵין דֹּאר, הָיוּ דֹּמֶן לָאֲדָמָה: שִׁיתֵמוֹ נְדִיבֵמוֹ כְּעֹרֵב וְכִזְאֵב, וּכְזֶבַח וּכְצַלְמֻנָּע כָּל נְסִיכֵמוֹ: אֲשֶׁר אָמְרוּ נִירְשָׁה לָּנוּ, אֵת נְאוֹת אֱלֹהִים: אֱלֹהַי, שִׁיתֵמוֹ כַגַּלְגַּל, כְּקַשׁ לִפְנֵי רוּחַ: כְּאֵשׁ תִּבְעַר יָעַר, וּכְלֶהָבָה תְּלַהֵט הָרִים: כֵּן תִּרְדְּפֵם בְּסַעֲרֶךָ, וּבְסוּפָתְךָ תְבַהֲלֵם: מַלֵּא פְנֵיהֶם קָלוֹן, וִיבַקְשׁוּ שִׁמְךָ יהוה: יֵבֹשׁוּ וְיִבָּהֲלוּ עֲדֵי עַד, וְיַחְפְּרוּ וְיֹאבֵדוּ: וְיֵדְעוּ כִּי אַתָּה שִׁמְךָ יהוה לְבַדֶּךָ, עֶלְיוֹן עַל כָּל הָאָרֶץ:","cond":["tishaaBeav","gedalya"]},{"kind":"special","text":"מזמור לצום גדליה ולעשרה בטבת:","cond":["tishaaBeav","10tevet"]},{"kind":"text","text":"שִׁיר מִזְמוֹר לְאָסָף: אֱלֹהִים אַל דֳּמִי לָךְ, אַל תֶּחֱרַשׁ וְאַל תִּשְׁקֹט אֵל: כִּי הִנֵּה אוֹיְבֶיךָ יֶהֱמָיוּן, וּמְשַׂנְאֶיךָ נָשְׂאוּ רֹאשׁ: עַל עַמְּךָ יַעֲרִימוּ סוֹד, וְיִתְיָעֲצוּ עַל צְפוּנֶיךָ: אָמְרוּ לְכוּ וְנַכְחִידֵם מִגּוֹי, וְלֹא יִזָּכֵר שֵׁם יִשְׂרָאֵל עוֹד: כִּי נוֹעֲצוּ לֵב יַחְדָּו, עָלֶיךָ בְּרִית יִכְרֹתוּ: אָהֳלֵי אֱדוֹם וְיִשְׁמְעֵאלִים, מוֹאָב וְהַגְרִים: גְּבָל וְעַמּוֹן וַעֲמָלֵק, פְּלֶשֶׁת עִם יֹשְׁבֵי צוֹר: גַּם אַשּׁוּר נִלְוָה עִמָּם, הָיוּ זְרוֹעַ לִבְנֵי לוֹט סֶלָה: עֲשֵׂה לָהֶם כְּמִדְיָן, כְּסִיסְרָא כְיָבִין בְּנַחַל קִישׁוֹן: נִשְׁמְדוּ בְעֵין דֹּאר, הָיוּ דֹּמֶן לָאֲדָמָה: שִׁיתֵמוֹ נְדִיבֵמוֹ כְּעֹרֵב וְכִזְאֵב, וּכְזֶבַח וּכְצַלְמֻנָּע כָּל נְסִיכֵמוֹ: אֲשֶׁר אָמְרוּ נִירְשָׁה לָּנוּ, אֵת נְאוֹת אֱלֹהִים: אֱלֹהַי, שִׁיתֵמוֹ כַגַּלְגַּל, כְּקַשׁ לִפְנֵי רוּחַ: כְּאֵשׁ תִּבְעַר יָעַר, וּכְלֶהָבָה תְּלַהֵט הָרִים: כֵּן תִּרְדְּפֵם בְּסַעֲרֶךָ, וּבְסוּפָתְךָ תְבַהֲלֵם: מַלֵּא פְנֵיהֶם קָלוֹן, וִיבַקְשׁוּ שִׁמְךָ יהוה: יֵבֹשׁוּ וְיִבָּהֲלוּ עֲדֵי עַד, וְיַחְפְּרוּ וְיֹאבֵדוּ: וְיֵדְעוּ כִּי אַתָּה שִׁמְךָ יהוה לְבַדֶּךָ, עֶלְיוֹן עַל כָּל הָאָרֶץ:","cond":["tishaaBeav","10tevet"]},{"kind":"special","text":"מזמור לתענית אסתר ולפורים:","cond":["tishaaBeav","purim"]},{"kind":"text","text":"לַמְנַצֵּחַ עַל אַיֶּלֶת הַשַּׁחַר, מִזְמוֹר לְדָוִד: אֵלִי אֵלִי לָמָה עֲזַבְתָּנִי, רָחוֹק מִישׁוּעָתִי דִּבְרֵי שַׁאֲגָתִי: אֱלֹהַי, אֶקְרָא יוֹמָם וְלֹא תַעֲנֶה, וְלַיְלָה וְלֹא דוּמִיָּה לִי: וְאַתָּה קָדוֹשׁ, יוֹשֵׁב תְּהִלּוֹת יִשְׂרָאֵל: בְּךָ בָּטְחוּ אֲבֹתֵינוּ, בָּטְחוּ וַתְּפַלְּטֵמוֹ: אֵלֶיךָ זָעֲקוּ וְנִמְלָטוּ, בְּךָ בָטְחוּ וְלֹא בוֹשׁוּ: וְאָנֹכִי תוֹלַעַת וְלֹא אִישׁ, חֶרְפַּת אָדָם וּבְזוּי עָם: כָּל רֹאַי יַלְעִגוּ לִי, יַפְטִירוּ בְשָׂפָה יָנִיעוּ רֹאשׁ: גֹּל אֶל יהוה יְפַלְּטֵהוּ, יַצִּילֵהוּ כִּי חָפֵץ בּוֹ: כִּי אַתָּה גֹחִי מִבָּטֶן, מַבְטִיחִי עַל שְׁדֵי אִמִּי: עָלֶיךָ הָשְׁלַכְתִּי מֵרָחֶם, מִבֶּטֶן אִמִּי אֵלִי אָתָּה אַל תִּרְחַק מִמֶּנִּי כִּי צָרָה קְרוֹבָה, כִּי אֵין עוֹזֵר: סְבָבוּנִי פָּרִים רַבִּים, אַבִּירֵי בָשָׁן כִּתְּרוּנִי: פָּצוּ עָלַי פִּיהֶם, אַרְיֵה טֹרֵף וְשֹׁאֵג: כַּמַּיִם נִשְׁפַּכְתִּי וְהִתְפָּרְדוּ כָּל עַצְמוֹתָי, הָיָה לִבִּי כַּדּוֹנָג, נָמֵס בְּתוֹךְ מֵעָי: יָבֵשׁ כַּחֶרֶשׂ כֹּחִי וּלְשׁוֹנִי מֻדְבָּק מַלְקוֹחָי, וְלַעֲפַר מָוֶת תִּשְׁפְּתֵנִי: כִּי סְבָבוּנִי כְּלָבִים, עֲדַת מְרֵעִים הִקִּיפוּנִי, כָּאֲרִי יָדַי וְרַגְלָי: אֲסַפֵּר כָּל עַצְמוֹתָי, הֵמָּה יַבִּיטוּ יִרְאוּ בִי: יְחַלְּקוּ בְגָדַי לָהֶם, וְעַל לְבוּשִׁי יַפִּילוּ גוֹרָל: וְאַתָּה יהוה אַל תִּרְחָק, אֱיָלוּתִי לְעֶזְרָתִי חוּשָׁה: הַצִּילָה מֵחֶרֶב נַפְשִׁי, מִיַּד כֶּלֶב יְחִידָתִי: הוֹשִׁיעֵנִי מִפִּי אַרְיֵה, וּמִקַּרְנֵי רֵמִים עֲנִיתָנִי: אֲסַפְּרָה שִׁמְךָ לְאֶחָי, בְּתוֹךְ קָהָל אֲהַלְלֶךָּ: יִרְאֵי יהוה הַלְלוּהוּ, כָּל זֶרַע יַעֲקֹב כַּבְּדוּהוּ, וְגוּרוּ מִמֶּנּוּ כָּל זֶרַע יִשְׂרָאֵל: כִּי לֹא בָזָה וְלֹא שִׁקַּץ עֱנוּת עָנִי, וְלֹא הִסְתִּיר פָּנָיו מִמֶּנּוּ, וּבְשַׁוְּעוֹ אֵלָיו שָׁמֵעַ: מֵאִתְּךָ תְהִלָּתִי בְּקָהָל רָב, נְדָרַי אֲשַׁלֵּם נֶגֶד יְרֵאָיו: יֹאכְלוּ עֲנָוִים וְיִשְׂבָּעוּ, יְהַלְלוּ יהוה דֹּרְשָׁיו, יְחִי לְבַבְכֶם לָעַד: יִזְכְּרוּ וְיָשֻׁבוּ אֶל יהוה כָּל אַפְסֵי אָרֶץ, וְיִשְׁתַּחֲווּ לְפָנֶיךָ כָּל מִשְׁפְּחוֹת גּוֹיִם: כִּי לַיהוה הַמְּלוּכָה, וּמֹשֵׁל בַּגּוֹיִם: אָכְלוּ וַיִּשְׁתַּחֲוּוּ כָּל דִּשְׁנֵי אֶרֶץ, לְפָנָיו יִכְרְעוּ כָּל יוֹרְדֵי עָפָר, וְנַפְשׁוֹ לֹא חִיָּה: זֶרַע יַעַבְדֶנּוּ, יְסֻפַּר לַאדֹנָי לַדּוֹר: יָבֹאוּ וְיַגִּידוּ צִדְקָתוֹ, לְעַם נוֹלָד כִּי עָשָׂה:","cond":["tishaaBeav","purim"]},{"kind":"special","text":"מזמור לתענית אסתר ולפורים:","cond":["tishaaBeav","ester"]},{"kind":"text","text":"לַמְנַצֵּחַ עַל אַיֶּלֶת הַשַּׁחַר, מִזְמוֹר לְדָוִד: אֵלִי אֵלִי לָמָה עֲזַבְתָּנִי, רָחוֹק מִישׁוּעָתִי דִּבְרֵי שַׁאֲגָתִי: אֱלֹהַי, אֶקְרָא יוֹמָם וְלֹא תַעֲנֶה, וְלַיְלָה וְלֹא דוּמִיָּה לִי: וְאַתָּה קָדוֹשׁ, יוֹשֵׁב תְּהִלּוֹת יִשְׂרָאֵל: בְּךָ בָּטְחוּ אֲבֹתֵינוּ, בָּטְחוּ וַתְּפַלְּטֵמוֹ: אֵלֶיךָ זָעֲקוּ וְנִמְלָטוּ, בְּךָ בָטְחוּ וְלֹא בוֹשׁוּ: וְאָנֹכִי תוֹלַעַת וְלֹא אִישׁ, חֶרְפַּת אָדָם וּבְזוּי עָם: כָּל רֹאַי יַלְעִגוּ לִי, יַפְטִירוּ בְשָׂפָה יָנִיעוּ רֹאשׁ: גֹּל אֶל יהוה יְפַלְּטֵהוּ, יַצִּילֵהוּ כִּי חָפֵץ בּוֹ: כִּי אַתָּה גֹחִי מִבָּטֶן, מַבְטִיחִי עַל שְׁדֵי אִמִּי: עָלֶיךָ הָשְׁלַכְתִּי מֵרָחֶם, מִבֶּטֶן אִמִּי אֵלִי אָתָּה אַל תִּרְחַק מִמֶּנִּי כִּי צָרָה קְרוֹבָה, כִּי אֵין עוֹזֵר: סְבָבוּנִי פָּרִים רַבִּים, אַבִּירֵי בָשָׁן כִּתְּרוּנִי: פָּצוּ עָלַי פִּיהֶם, אַרְיֵה טֹרֵף וְשֹׁאֵג: כַּמַּיִם נִשְׁפַּכְתִּי וְהִתְפָּרְדוּ כָּל עַצְמוֹתָי, הָיָה לִבִּי כַּדּוֹנָג, נָמֵס בְּתוֹךְ מֵעָי: יָבֵשׁ כַּחֶרֶשׂ כֹּחִי וּלְשׁוֹנִי מֻדְבָּק מַלְקוֹחָי, וְלַעֲפַר מָוֶת תִּשְׁפְּתֵנִי: כִּי סְבָבוּנִי כְּלָבִים, עֲדַת מְרֵעִים הִקִּיפוּנִי, כָּאֲרִי יָדַי וְרַגְלָי: אֲסַפֵּר כָּל עַצְמוֹתָי, הֵמָּה יַבִּיטוּ יִרְאוּ בִי: יְחַלְּקוּ בְגָדַי לָהֶם, וְעַל לְבוּשִׁי יַפִּילוּ גוֹרָל: וְאַתָּה יהוה אַל תִּרְחָק, אֱיָלוּתִי לְעֶזְרָתִי חוּשָׁה: הַצִּילָה מֵחֶרֶב נַפְשִׁי, מִיַּד כֶּלֶב יְחִידָתִי: הוֹשִׁיעֵנִי מִפִּי אַרְיֵה, וּמִקַּרְנֵי רֵמִים עֲנִיתָנִי: אֲסַפְּרָה שִׁמְךָ לְאֶחָי, בְּתוֹךְ קָהָל אֲהַלְלֶךָּ: יִרְאֵי יהוה הַלְלוּהוּ, כָּל זֶרַע יַעֲקֹב כַּבְּדוּהוּ, וְגוּרוּ מִמֶּנּוּ כָּל זֶרַע יִשְׂרָאֵל: כִּי לֹא בָזָה וְלֹא שִׁקַּץ עֱנוּת עָנִי, וְלֹא הִסְתִּיר פָּנָיו מִמֶּנּוּ, וּבְשַׁוְּעוֹ אֵלָיו שָׁמֵעַ: מֵאִתְּךָ תְהִלָּתִי בְּקָהָל רָב, נְדָרַי אֲשַׁלֵּם נֶגֶד יְרֵאָיו: יֹאכְלוּ עֲנָוִים וְיִשְׂבָּעוּ, יְהַלְלוּ יהוה דֹּרְשָׁיו, יְחִי לְבַבְכֶם לָעַד: יִזְכְּרוּ וְיָשֻׁבוּ אֶל יהוה כָּל אַפְסֵי אָרֶץ, וְיִשְׁתַּחֲווּ לְפָנֶיךָ כָּל מִשְׁפְּחוֹת גּוֹיִם: כִּי לַיהוה הַמְּלוּכָה, וּמֹשֵׁל בַּגּוֹיִם: אָכְלוּ וַיִּשְׁתַּחֲוּוּ כָּל דִּשְׁנֵי אֶרֶץ, לְפָנָיו יִכְרְעוּ כָּל יוֹרְדֵי עָפָר, וְנַפְשׁוֹ לֹא חִיָּה: זֶרַע יַעַבְדֶנּוּ, יְסֻפַּר לַאדֹנָי לַדּוֹר: יָבֹאוּ וְיַגִּידוּ צִדְקָתוֹ, לְעַם נוֹלָד כִּי עָשָׂה:","cond":["tishaaBeav","ester"]},{"kind":"special","text":"מזמור לחנוכה:","cond":["tishaaBeav","chanuka"]},{"kind":"text","text":"מִזְמוֹר שִׁיר חֲנֻכַּת הַבַּיִת לְדָוִד: אֲרוֹמִמְךָ יהוה כִּי דִלִּיתָנִי, וְלֹא שִׂמַּחְתָּ אֹיְבַי לִי: יהוה אֱלֹהָי שִׁוַּעְתִּי אֵלֶיךָ וַתִּרְפָּאֵנִי: יהוה, הֶעֱלִיתָ מִן שְׁאוֹל נַפְשִׁי, חִיִּיתַנִי מִיָּרְדִי בוֹר: זַמְּרוּ לַיהוה חֲסִידָיו וְהוֹדוּ לְזֵכֶר קָדְשׁוֹ: כִּי רֶגַע בְּאַפּוֹ חַיִּים בִּרְצוֹנוֹ, בָּעֶרֶב יָלִין בֶּכִי וְלַבֹּקֶר רִנָּה: וַאֲנִי אָמַרְתִּי בְשַׁלְוִי בַּל אֶמּוֹט לְעוֹלָם: יהוה בִּרְצוֹנְךָ הֶעֱמַדְתָּה לְהַרְרִי עֹז, הִסְתַּרְתָּ פָנֶיךָ הָיִיתִי נִבְהָל: אֵלֶיךָ יהוה אֶקְרָא וְאֶל אֲדֹנָי אֶתְחַנָּן: מַה בֶּצַע בְּדָמִי בְּרִדְתִּי אֶל שָׁחַת, הֲיוֹדְךָ עָפָר הֲיַגִּיד אֲמִתֶּךָ: שְׁמַע יהוה וְחָנֵּנִי, יהוה הֱיֵה עֹזֵר לִי: הָפַכְתָּ מִסְפְּדִי לְמָחוֹל לִי, פִּתַּחְתָּ שַׂקִּי וַתְּאַזְּרֵנִי שִׂמְחָה: לְמַעַן יְזַמֶּרְךָ כָבוֹד וְלֹא יִדֹּם, יהוה אֱלֹהַי לְעוֹלָם אוֹדֶךָּ:","cond":["tishaaBeav","chanuka"]},{"kind":"instruction","text":"קדיש יהא שלמא","cond":["tishaaBeav"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא, חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה וְשֵיזָבָא וּרְפוּאָה וּגְאֻלָּה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה, לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav"]},{"kind":"text","text":"עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav"]},{"kind":"instruction","text":"סוף התפילה","cond":["tishaaBeav"]},{"kind":"text","text":"קַוֵּה אֶל יהוה, חֲזַק וְיַאֲמֵץ לִבֶּךָ, וְקַוֵּה אֶל יהוה: אֵין קָדוֹשׁ כַּיהוה כִּי אֵין בִּלְתֶּךָ, וְאֵין צוּר כֵּאלֹהֵינוּ: כִּי מִי אֱלוֹהַּ מִבַּלְעֲדֵי יהוה, וּמִי צוּר זוּלָתִי אֱלֹהֵינוּ:\n\nאֵין כֵּאלֹהֵינוּ, אֵין כַּאדוֹנֵנוּ, אֵין כְּמַלְכֵּנוּ, אֵין כְּמוֹשִׁיעֵנוּ. מִי כֵּאלֹהֵינוּ, מִי כַּאדוֹנֵנוּ, מִי כְּמַלְכֵּנוּ, מִי כְּמוֹשִׁיעֵנוּ. נוֹדֶה לֵאלֹהֵינוּ, נוֹדֶה לַאדוֹנֵנוּ, נוֹדֶה לְמַלְכֵּנוּ, נוֹדֶה לְמוֹשִׁיעֵנוּ. בָּרוּךְ אֱלֹהֵינוּ, בָּרוּךְ אֲדוֹנֵנוּ, בָּרוּךְ מַלְכֵּנוּ, בָּרוּךְ מוֹשִׁיעֵנוּ. אַתָּה הוּא אֱלֹהֵינוּ, אַתָּה הוּא אֲדוֹנֵנוּ, אַתָּה הוּא מַלְכֵּנוּ, אַתָּה הוּא מוֹשִׁיעֵנוּ. אַתָּה תוֹשִׁיעֵנוּ. אַתָּה תָקוּם תְּרַחֵם צִיּוֹן, כִּי עֵת לְחֶנְנָהּ, כִּי בָא מוֹעֵד:\n\nאַתָּה הוּא יהוה אֱלֹהֵינוּ שֶׁהִקְטִירוּ אֲבוֹתֵינוּ לְפָנֶיךָ אֶת קְטֹרֶת הַסַּמִּים, בִּזְמַן שֶׁבֵּית הַמִּקְדָּשׁ קַיָּם, כַּאֲשֶׁר צִוִּיתָ אוֹתָם עַל יַד מֹשֶׁה נְבִיאָךְ כַּכָּתוּב בְּתוֹרָתָךְ:\n\nוַיֹּאמֶר יהוה אֶל מֹשֶׁה, קַח לְךָ סַמִּים, נָטָף וּשְׁחֵלֶת וְחֶלְבְּנָה, סַמִּים, וּלְבֹנָה זַכָּה, בַּד בְּבַד יִהְיֶה: וְעָשִׂיתָ אֹתָהּ קְטֹרֶת, רֹקַח, מַעֲשֵׂה רוֹקֵחַ, מְמֻלָּח, טָהוֹר קֹדֶשׁ: וְשָׁחַקְתָּ מִמֶּנָּה הָדֵק, וְנָתַתָּה מִמֶּנָּה לִפְנֵי הָעֵדֻת בְּאֹהֶל מוֹעֵד, אֲשֶׁר אִוָּעֵד לְךָ שָׁמָּה, קֹדֶשׁ קָדָשִׁים תִּהְיֶה לָכֶם: וְנֶאֱמַר: וְהִקְטִיר עָלָיו אַהֲרֹן קְטֹרֶת סַמִּים, בַּבֹּקֶר בַּבֹּקֶר, בְּהֵיטִיבוֹ אֶת הַנֵּרֹת, יַקְטִירֶנָּה: וּבְהַעֲלֹת אַהֲרֹן אֶת הַנֵּרֹת בֵּין הָעֲרְבַּיִם, יַקְטִירֶנָּה, קְטֹרֶת תָּמִיד לִפְנֵי יהוה, לְדֹרֹתֵיכֶם:\n\nתָּנוּ רַבָּנָן: פִּטּוּם הַקְּטֹרֶת כֵּיצַד? שְׁלֹשׁ מֵאוֹת וְשִׁשִּׁים וּשְׁמוֹנָה מָנִים הָיוּ בָהּ, שְׁלֹשׁ מֵאוֹת וְשִׁשִּׁים וַחֲמִשָּׁה כְּמִנְיַן יְמוֹת הַחַמָּה מָנֶה בְכָל יוֹם, מַחֲצִיתוֹ בַבֹּקֶר וּמַחֲצִיתוֹ בַעָרֶב, וּשְׁלֹשָׁה מָנִים יְתֵרִים שֶׁמֵּהֶם מַכְנִיס כֹּהֵן גָּדוֹל וְנוֹטֵל מֵהֶם מָלֵא חָפְנָיו בְּיוֹם הָכִּיפוּרים, מַחֲזִירָן לְמַכְתֶּשֶׁת בְּעֶרֶב יוֹם הַכִּיפוּרִים כְּדֵי לְקַיֵּם מִצְוַת דַּקָּה מִן הַדַּקָּה, וְאַחַד עָשָׂר סַמָּנִים הָיוּ בָהּ וְאֵלּוּ הֵן:\n\nהַצֳּרִי וְהַצִּפּוֹרֶן וְהַחֶלְבְּנָה וְהַלְּבוֹנָה, מִשְׁקַל שִׁבְעִים שִׁבְעִים מָנֶה. מוֹר, וּקְצִיעָה וְשִׁבֹּלֶת נֵרְדְּ וְכַרְכֹּם, מִשְׁקַל שִׁשָּׁה עָשָׂר שִׁשָּׁה עָשָׂר מָנֶה. הַקֹשְׂט שְׁנֵים עָשָׂר, קִלּוּפָה שְׁלֹשָׁה, קִנָּמוֹן תִּשְׁעָה, בּוֹרִית כַּרְשִינָה תִּשְׁעָה קַבִּין, יֵין קַפְרִיסִין סְאִין תְּלָת וְקַבִּין תְּלָתָא, וְאִם לֹא מָצָא יֵין קַפְרִיסִין, מֵבִיא חֲמַר חִוָר עַתִּיק. מֶלַח סְדוֹמִית רוֹבַע, מַעֲלֶה עָשָׁן כָּל שֶׁהוּא. רִבִּי נָתַן הַבַּבְלִי אוֹמֵר: אַף כִּפַּת הַיַּרְדֵּן כָּל שֶׁהִיא, אִם נָתַן בָּהּ דְּבַשׁ פְּסָלָהּ, וְאִם חִסֵּר אַחַת מִכָּל סַמֲמָנֶיהָ, חַיָּב מִיתָה.\n\nרַבָּן שִׁמְעוֹן בֶּן גַּמְלִיאֵל אוֹמֵר: הַצֳּרִי אֵינוֹ אֶלָּא שְׁרָף הַנּוֹטֵף מֵעֲצֵי הַקְּטָף. בּוֹרִית כַּרְשִׁינָה לְמָה הִיא בָאָה? כְּדֵי לְשַׁפּוֹת בָּהּ אֶת הַצִּפּוֹרֶן, כְּדֵי שֶׁתְּהֵא נָאֶה. יַיִן קַפְרִיסִין לְמַה הוּא בָא? כְּדֵי לִשְׁרוֹת בּוֹ אֶת הַצִּפּוֹרֶן, כְּדֵי שֶׁתְּהֵא עַזָּה. וַהֲלֹא מִי רַגְלַיִם יָפִין לָהּ, אֶלָּא שֶׁאֵין מַכְנִיסִין מִי רַגְלַיִם בַּמִּקְדָּשׁ מִפְּנֵי הַכָּבוֹד.\n\nתַּנְיָא: רִבִּי נָתַן אוֹמֵר: כְּשֶׁהוּא שׁוֹחֵק, אוֹמֵר: \"הָדֵק הֵיטֵב, הֵיטֵב הָדֵק\", מִפְּנֵי שֶׁהַקּוֹל יָפֶה לַבְּשָׂמִים. פִּטְּמָהּ לַחֲצָאִין כְּשֵׁרָה, לְשָׁלִישׁ וּלְרָבִיעַ, לֹא שָׁמַעְנוּ. אָמַר רִבִּי יְהוּדָה: זֶה הַכְּלָל: אִם כְּמִדָּתָהּ - כְּשֵׁרָה לַחֲצָאִין, וְאִם חִסֵּר אַחַת מִכָּל סַמֲמָנֶיהָ, חַיָּב מִיתָה.\n\nתָּנֵי בַר קַפָּרָא: אַחַת לְשִׁשִּׁים אוֹ לְשִׁבְעִים שָׁנָה הָיְתָה בָּאָה שֶׁל שִׁירַיִם לַחֲצָאִין. וְעוֹד תָּנֵי בַר קַפָּרָא: אִלּוּ הָיָה נוֹתֵן בָּהּ קָרְטוֹב שֶׁל דְּבַשׁ, אֵין אָדָם יָכוֹל לַעֲמֹד מִפְּנֵי רֵיחָהּ. וְלָמָּה אֵין מְעָרְבִין בָּהּ דְּבַשׁ? מִפְּנֵי שֶׁהַתּוֹרָה אָמְרָה: כִּי כָל שְׂאֹר וְכָל דְּבַשׁ לֹא תַקְטִירוּ מִמֶּנּוּ אִשֶּׁה לַיהוה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה: יהוה צְבָאוֹת, אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ: וְעָרְבָה לַיהוה מִנְחַת יְהוּדָה וִירוּשָׁלִָם כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמֹנִיּוֹת:\n\nתָּנָא דְּבֵי אֵלִיָּהוּ: כָּל הַשּׁוֹנֶה הֲלָכוֹת בְּכָל יוֹם, מֻבְטָח לוֹ שֶׁהוּא בֶּן הָעוֹלָם הַבָּא, שֶׁנֶּאֱמַר: \"הֲלִיכוֹת עוֹלָם לוֹ:\" אֶל תִּקְרֵי \"הֲלִיכוֹת\", אֶלָּא \"הֲלָכוֹת\". אָמַר רִבִּי אֶלְעָזָר אָמַר רִבִּי חֲנִינָא: תַּלְמִידֵי חֲכָמִים מַרְבִּים שָׁלוֹם בָּעוֹלָם, שֶׁנֶּאֱמַר: \"וְכָל בָּנַיִךָ לִמּוּדֵי יהוה, וְרַב שְׁלוֹם בָּנָיִךָ:\" אֶל תִּקְרֵי \"בָנַיִךְ\" אֶלָּא \"בוֹנָיִךְ\". יְהִי שָׁלוֹם בְּחֵילֵךְ שַׁלְוָה בְּאַרְמְנוֹתָיִךְ: לְמַעַן אָחַי וְרֵעָי אֲדַבְּרָה נָא שָׁלוֹם בָּךְ: לְמַעַן בֵּית יהוה אֱלֹהֵינוּ אֲבַקְשָׁה טוֹב לְךָ: וּרְאֵה בָנִים לְבָנֶיךָ שָׁלוֹם עַל יִשְׂרָאֵל: שָׁלוֹם רַב לְאֹהֲבֵי תּוֹרָתֶךְ וְאֵין לָמוֹ מִכְשׁוֹל: יהוה, עֹז לְעַמּוֹ יִתֵּן, יהוה יְבָרֵךְ אֶת עַמּוֹ בַשָׁלוֹם:","cond":["tishaaBeav"]},{"kind":"instruction","text":"קדיש יהא שלמא","cond":["tishaaBeav"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא, חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה וְשֵיזָבָא וּרְפוּאָה וּגְאֻלָּה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה, לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav"]},{"kind":"text","text":"עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav"]}],"arvit":[{"kind":"text","text":"לַמְנַצֵּחַ עַל אַיֶּלֶת הַשַּׁחַר, מִזְמוֹר לְדָוִד: אֵלִי אֵלִי לָמָה עֲזַבְתָּנִי, רָחוֹק מִישׁוּעָתִי דִּבְרֵי שַׁאֲגָתִי: אֱלֹהַי, אֶקְרָא יוֹמָם וְלֹא תַעֲנֶה, וְלַיְלָה וְלֹא דוּמִיָּה לִי: וְאַתָּה קָדוֹשׁ, יוֹשֵׁב תְּהִלּוֹת יִשְׂרָאֵל: בְּךָ בָּטְחוּ אֲבֹתֵינוּ, בָּטְחוּ וַתְּפַלְּטֵמוֹ: אֵלֶיךָ זָעֲקוּ וְנִמְלָטוּ, בְּךָ בָטְחוּ וְלֹא בוֹשׁוּ: וְאָנֹכִי תוֹלַעַת וְלֹא אִישׁ, חֶרְפַּת אָדָם וּבְזוּי עָם: כָּל רֹאַי יַלְעִגוּ לִי, יַפְטִירוּ בְשָׂפָה יָנִיעוּ רֹאשׁ: גֹּל אֶל יהוה יְפַלְּטֵהוּ, יַצִּילֵהוּ כִּי חָפֵץ בּוֹ: כִּי אַתָּה גֹחִי מִבָּטֶן, מַבְטִיחִי עַל שְׁדֵי אִמִּי: עָלֶיךָ הָשְׁלַכְתִּי מֵרָחֶם, מִבֶּטֶן אִמִּי אֵלִי אָתָּה אַל תִּרְחַק מִמֶּנִּי כִּי צָרָה קְרוֹבָה, כִּי אֵין עוֹזֵר: סְבָבוּנִי פָּרִים רַבִּים, אַבִּירֵי בָשָׁן כִּתְּרוּנִי: פָּצוּ עָלַי פִּיהֶם, אַרְיֵה טֹרֵף וְשֹׁאֵג: כַּמַּיִם נִשְׁפַּכְתִּי וְהִתְפָּרְדוּ כָּל עַצְמוֹתָי, הָיָה לִבִּי כַּדּוֹנָג, נָמֵס בְּתוֹךְ מֵעָי: יָבֵשׁ כַּחֶרֶשׂ כֹּחִי וּלְשׁוֹנִי מֻדְבָּק מַלְקוֹחָי, וְלַעֲפַר מָוֶת תִּשְׁפְּתֵנִי: כִּי סְבָבוּנִי כְּלָבִים, עֲדַת מְרֵעִים הִקִּיפוּנִי, כָּאֲרִי יָדַי וְרַגְלָי: אֲסַפֵּר כָּל עַצְמוֹתָי, הֵמָּה יַבִּיטוּ יִרְאוּ בִי: יְחַלְּקוּ בְגָדַי לָהֶם, וְעַל לְבוּשִׁי יַפִּילוּ גוֹרָל: וְאַתָּה יהוה אַל תִּרְחָק, אֱיָלוּתִי לְעֶזְרָתִי חוּשָׁה: הַצִּילָה מֵחֶרֶב נַפְשִׁי, מִיַּד כֶּלֶב יְחִידָתִי: הוֹשִׁיעֵנִי מִפִּי אַרְיֵה, וּמִקַּרְנֵי רֵמִים עֲנִיתָנִי: אֲסַפְּרָה שִׁמְךָ לְאֶחָי, בְּתוֹךְ קָהָל אֲהַלְלֶךָּ: יִרְאֵי יהוה הַלְלוּהוּ, כָּל זֶרַע יַעֲקֹב כַּבְּדוּהוּ, וְגוּרוּ מִמֶּנּוּ כָּל זֶרַע יִשְׂרָאֵל: כִּי לֹא בָזָה וְלֹא שִׁקַּץ עֱנוּת עָנִי, וְלֹא הִסְתִּיר פָּנָיו מִמֶּנּוּ, וּבְשַׁוְּעוֹ אֵלָיו שָׁמֵעַ: מֵאִתְּךָ תְהִלָּתִי בְּקָהָל רָב, נְדָרַי אֲשַׁלֵּם נֶגֶד יְרֵאָיו: יֹאכְלוּ עֲנָוִים וְיִשְׂבָּעוּ, יְהַלְלוּ יהוה דֹּרְשָׁיו, יְחִי לְבַבְכֶם לָעַד: יִזְכְּרוּ וְיָשֻׁבוּ אֶל יהוה כָּל אַפְסֵי אָרֶץ, וְיִשְׁתַּחֲווּ לְפָנֶיךָ כָּל מִשְׁפְּחוֹת גּוֹיִם: כִּי לַיהוה הַמְּלוּכָה, וּמֹשֵׁל בַּגּוֹיִם: אָכְלוּ וַיִּשְׁתַּחֲוּוּ כָּל דִּשְׁנֵי אֶרֶץ, לְפָנָיו יִכְרְעוּ כָּל יוֹרְדֵי עָפָר, וְנַפְשׁוֹ לֹא חִיָּה: זֶרַע יַעַבְדֶנּוּ, יְסֻפַּר לַאדֹנָי לַדּוֹר: יָבֹאוּ וְיַגִּידוּ צִדְקָתוֹ, לְעַם נוֹלָד כִּי עָשָׂה:","cond":["purim"]},{"kind":"special","text":"תפילת יום העצמאות ויום שחרור ירושלים","cond":["yerushalayim"]},{"kind":"instruction","text":"לפני התפילה אומרים:","cond":["yerushalayim"]},{"kind":"instruction","text":"תהלים פרק ק\"ז","cond":["yerushalayim"]},{"kind":"text","text":"הֹדוּ לַיהוה כִּי-טוֹב, כִּי לְעוֹלָם חַסְדּוֹ: יֹאמְרוּ גְּאוּלֵי יהוה אֲשֶׁר גְּאָלָם מִיַּד-צָר: וּמֵאֲרָצוֹת קִבְּצָם, מִמִּזְרָח וּמִמַּעֲרָב מִצָּפוֹן וּמִיָּם: תָּעוּ בַמִּדְבָּר בִּישִׁימוֹן דָּרֶךְ, עִיר מוֹשָׁב לֹא מָצָאוּ: רְעֵבִים גַּם-צְמֵאִים, נַפְשָׁם בָּהֶם תִּתְעַטָּף: וַיִּצְעֲקוּ אֶל-יהוה בַּצַּר לָהֶם, מִמְּצוּקוֹתֵיהֶם יַצִּילֵם: וַיַּדְרִיכֵם בְּדֶרֶךְ יְשָׁרָה, לָלֶכֶת אֶל-עִיר מוֹשָׁב: יוֹדוּ לַיהוה חַסְדּוֹ, וְנִפְלְאוֹתָיו לִבְנֵי אָדָם: כִּי-הִשְׂבִּיעַ נֶפֶשׁ שׁוֹקֵקָה, וְנֶפֶשׁ רְעֵבָה מִלֵּא-טוֹב: יֹשְׁבֵי חֹשֶׁךְ וְצַלְמָוֶת, אֲסִירֵי עֳנִי וּבַרְזֶל: כִּי-הִמְרוּ אִמְרֵי-אֵל, וַעֲצַת עֶלְיוֹן נָאָצוּ: וַיַּכְנַע בֶּעָמָל לִבָּם, כָּשְׁלוּ וְאֵין עֹזֵר: וַיִּזְעֲקוּ אֶל-יהוה בַּצַּר לָהֶם, מִמְּצֻקוֹתֵיהֶם יוֹשִׁיעֵם: יוֹצִיאֵם מֵחֹשֶׁךְ וְצַלְמָוֶת, וּמוֹסְרוֹתֵיהֶם יְנַתֵּק: יוֹדוּ לַיהוה חַסְדּוֹ, וְנִפְלְאוֹתָיו לִבְנֵי אָדָם: כִּי-שִׁבַּר דַּלְתוֹת נְחֹשֶׁת, וּבְרִיחֵי בַרְזֶל גִּדֵּעַ: אֱוִלִים מִדֶּרֶךְ פִּשְׁעָם, וּמֵעֲוׂנֹתֵיהֶם יִתְעַנּוּ: כָּל-אֹכֶל תְּתַעֵב נַפְשָׁם, וַיַּגִּיעוּ עַד-שַׁעֲרֵי מָוֶת: וַיִּזְעֲקוּ אֶל-יהוה בַּצַּר לָהֶם, מִמְּצֻקוֹתֵיהֶם יוֹשִׁיעֵם: יִשְׁלַח דְּבָרוֹ וְיִרְפָּאֵם, וִימַלֵּט מִשְּׁחִיתוֹתָם: יוֹדוּ לַיהוה חַסְדּוֹ, וְנִפְלְאוֹתָיו לִבְנֵי אָדָם: וְיִזְבְּחוּ זִבְחֵי תוֹדָה, וִיסַפְּרוּ מַעֲשָׂיו בְּרִנָּה: יוֹרְדֵי הַיָּם בָּאֳנִיּוֹת, עֹשֵׂי מְלָאכָה בְּמַיִם רַבִּים: הֵמָּה רָאוּ מַעֲשֵׂי יהוה וְנִפְלְאוֹתָיו בִּמְצוּלָה: וַיּאמֶר, וַיַּעֲמֵד רוּחַ סְעָרָה, וַתְּרוֹמֵם גַּלָּיו: יַעֲלוּ שָׁמַיִם יֵרְדוּ תְהוֹמוֹת, נַפְשָׁם בְּרָעָה תִתְמוֹגָג: יָחוֹגּוּ וְיָנוּעוּ כַּשִּׁכּוֹר, וְכָל-חָכְמָתָם תִּתְבַּלָּע: וַיִּצְעֲקוּ אֶל-יהוה בַּצַּר לָהֶם, וּמִמְּצוּקתֵיהֶם יוֹצִיאֵם: יָקֵם סְעָרָה לִדְמָמָה, וַיֶּחֱשׁוּ גַּלֵּיהֶם: וַיִּשְׂמְחוּ כִי-יִשְׁתֹּקוּ, וַיַּנְחֵם אֶל-מְחוֹז חֶפְצָם: יוֹדוּ לַיהוה חַסְדּוֹ, וְנִפְלְאוֹתָיו לִבְנֵי אָדָם: וִירוֹמְמוּהוּ בִּקְהַל-עָם, וּבְמוֹשַׁב זְקֵנִים יְהַלְלוּהוּ: יָשֵׂם נְהָרוֹת לְמִדְבָּר, וּמֹצָאֵי מַיִם לְצִמָּאוֹן: אֶרֶץ פְּרִי לִמְלֵחָה מֵרָעַת יוֹשְׁבֵי בָהּ: יָשֵׂם מִדְבָּר לַאֲגַם-מַיִם, וְאֶרֶץ צִיָּה לְמֹצָאֵי מָיִם: וַיּוֹשֶׁב שָׁם רְעֵבִים, וַיְכוֹנְנוּ עִיר מוֹשָׁב: וַיִּזְרְעוּ שָׂדוֹת וַיִּטְּעוּ כְרָמִים, וַיַּעֲשׂוּ פְּרִי תְבוּאָה: וַיְבָרְכֵם וַיִּרְבּוּ מְאֹד, וּבְהֶמְתָּם לֹא יַמְעִיט: וַיִּמְעֲטוּ וַיָּשֹׁחוּ מֵעֹצֶר רָעָה וְיָגוֹן: שֹׁפֵךְ בּוּז עַל-נְדִיבִים, וַיַּתְעֵם בְּתֹהוּ לֹא-דָרֶךְ: וַיְשַׂגֵּב אֶבְיוֹן מֵעוֹנִי, וַיָּשֶׂם כַּצֹּאן מִשְׁפָּחוֹת: יִרְאוּ יְשָׁרִים וְיִשְׂמָחוּ, וְכָל-עַוְלָה קָפְצָה פִּיהָ: מִי-חָכָם וְיִשְׁמָר-אֵלֶּה, וְיִתְבּוֹנְנוּ חַסְדֵּי יהוה:","cond":["yerushalayim"]},{"kind":"instruction","text":"תהלים פרק צ\"ז","cond":["yerushalayim"]},{"kind":"text","text":"יהוה מָלָךְ תָּגֵל הָאָרֶץ, יִשְׂמְחוּ אִיִּים רַבִּים: עָנָן וַעֲרָפֶל סְבִיבָיו, צֶדֶק וּמִשְׁפָּט מְכוֹן כִּסְאוֹ: אֵשׁ לְפָנָיו תֵּלֵךְ וּתְלַהֵט סָבִיב צָרָיו: הֵאִירוּ בְרָקָיו תֵּבֵל, רָאֲתָה וַתָּחֵל הָאָרֶץ: הָרִים כַּדּוֹנַג נָמַסּוּ, מִלִּפְנֵי יהוה, מִלִּפְנֵי אֲדוֹן כָּל-הָאָרֶץ: הִגִּידוּ הַשָּׁמַיִם צִדְקוֹ וְרָאוּ כָל-הָעַמִּים כְּבוֹדוֹ: יֵבשׁוּ כָּל-עֹבְדֵי פֶסֶל הַמִּתְהַלְלִים בָּאֱלִילִים, הִשְׁתַּחֲווּ-לוֹ כָּל-אֱלֹהִים: שָׁמְעָה וַתִּשְׂמַח צִיּוֹן וַתָּגֵלְנָה בְּנוֹת יְהוּדָה, לְמַעַן מִשְׁפָּטֶיךָ, יהוה: כִּי-אַתָּה יהוה עֶלְיוֹן עַל-כָּל-הָאָרֶץ, מְאֹד נַעֲלֵיתָ עַל-כָּל-אֱלֹהִים: אֹהֲבֵי יהוה שִׂנְאוּ רָע, שֹׁמֵר נַפְשׁוֹת חֲסִידָיו, מִיַּד רְשָׁעִים יַצִּילֵם: אוֹר זָרֻעַ לַצַּדִּיק וּלְיִשְׁרֵי-לֵב שִׂמְחָה: שִׂמְחוּ צַדִּיקִים בַּיהוה, וְהוֹדוּ לְזֵכֶר קָדְשׁוֹ:","cond":["yerushalayim"]},{"kind":"instruction","text":"תהלים פרק צ\"ח","cond":["yerushalayim"]},{"kind":"text","text":"מִזְמוֹר, שִׁירוּ לַיהוה שִׁיר חָדָשׁ כִּי-נִפְלָאוֹת עָשָׂה, הוֹשִׁיעָה-לּוֹ יְמִינוֹ וּזְרוֹעַ קָדְשׁוֹ: הוֹדִיעַ יהוה יְשׁוּעָתוֹ, לְעֵינֵי הַגּוֹיִם גִּלָּה צִדְקָתוֹ: זָכַר חַסְדּוֹ וֶאֱמוּנָתוֹ לְבֵית יִשְׂרָאֵל, רָאוּ כָל-אַפְסֵי-אָרֶץ אֵת יְשׁוּעַת אֱלֹהֵינוּ: הָרִיעוּ לַיהוה כָּל-הָאָרֶץ, פִּצְחוּ וְרַנְּנוּ וְזַמֵּרוּ: זַמְּרוּ לַיהוה בְּכִנּוֹר, בְּכִנּוֹר וְקוֹל זִמְרָה: בַּחֲצֹצְרוֹת וְקוֹל שׁוֹפָר, הָרִיעוּ לִפְנֵי הַמֶּלֶךְ יהוה: יִרְעַם הַיָּם וּמְלֹאוֹ, תֵּבֵל וְישְׁבֵי בָהּ: נְהָרוֹת יִמְחֲאוּ-כָף, יַחַד הָרִים יְרַנֵּנוּ: לִפְנֵי-יהוה כִּי בָא לִשְׁפֹּט הָאָרֶץ, יִשְׁפֹּט-תֵּבֵל בְּצֶדֶק וְעַמִּים בְּמֵישָׁרִים:","cond":["yerushalayim"]},{"kind":"instruction","text":"ואומרים בית בית:","cond":["yerushalayim"]},{"kind":"text","text":"הִתְעוֹרְרִי הִתְעוֹרְרִי,\nכִּי בָא אוֹרֵךְ קוּמִי אוֹרִי.\nעוּרִי עוּרִי שִׁיר דַּבֵּרִי,\nכְּבוֹד יהוה עָלַיִךְ נִגְלָה.\nזֶה הַיּוֹם עָשָׂה יהוה, נָגִילָה וְנִשְׂמְחָה בוֹ:\n\nלֹא תֵּבֹשִׁי וְלֹא תִּכָּלְמִי\nמַה תִּשְׁתּוֹחֲחִי וּמַה תֶּהֱמִי\nבָּךְ יֶחֱסוּ עֲנִיֵּי עַמִּי\nוְנִבְנְתָה עִיר עַל תִּלָּהּ\nזֶה הַיּוֹם עָשָׂה יהוה, נָגִילָה וְנִשְׂמְחָה בוֹ:\n\nיָמִין וּשְׂמֹאל תִּפְרֹצִי\nוְאֶת יהוה תַּעֲרִיצִי\nעַל יַד אִישׁ בֶּן פַּרְצִי\nוְנִשְׂמְחָה וְנָגִילָה\nזֶה הַיּוֹם עָשָׂה יהוה, נָגִילָה וְנִשְׂמְחָה בוֹ:","cond":["yerushalayim"]},{"kind":"header","text":"תפילת ערבית","cond":["yerushalayim"]},{"kind":"special","text":"בָּרְכִי נַפְשִׁי אֶת יהוה, יהוה אֱלֹהַי גָּדַלְתָּ מְּאֹד, הוֹד וְהָדָר לָבָשְׁתָּ:\nעֹטֶה אוֹר כַּשַּׂלְמָה נוֹטֶה שָׁמַיִם כַּיְרִיעָה:\nהַמְקָרֶה בַמַּיִם עֲלִיּוֹתָיו, הַשָּׂם עָבִים רְכוּבוֹ, הַמְהַלֵּךְ עַל כַּנְפֵי רוּחַ:\nעֹשֶׂה מַלְאָכָיו רוּחוֹת, מְשָׁרְתָיו אֵשׁ לֹהֵט:\nיָסַד אֶרֶץ עַל מְכוֹנֶיהָ, בַּל תִּמּוֹט עוֹלָם וָעֶד:\nתְּהוֹם כַּלְּבוּשׁ כִּסִּיתוֹ, עַל הָרִים יַעַמְדוּ מָיִם:\nמִן גַּעֲרָתְךָ יְנוּסוּן, מִן קוֹל רַעַמְךָ יֵחָפֵזוּן:\nיַעֲלוּ הָרִים, יֵרְדוּ בְקָעוֹת, אֶל מְקוֹם זֶה יָסַדְתָּ לָהֶם:\nגְּבוּל שַׂמְתָּ בַּל יַעֲבֹרוּן, בַּל יְשׁוּבוּן לְכַסּוֹת הָאָרֶץ:\nהַמְשַׁלֵּחַ מַעְיָנִים בַּנְּחָלִים בֵּין הָרִים יְהַלֵּכוּן:","cond":["rh"]},{"kind":"special","text":"יַשְׁקוּ כָּל חַיְתוֹ שָׂדָי, יִשְׁבְּרוּ פְרָאִים צְמָאָם:\nעֲלֵיהֶם עוֹף הַשָּׁמַיִם יִשְׁכּוֹן, מִבֵּין עֳפָאיִם יִתְּנוּ קוֹל:\nמַשְׁקֶה הָרִים מֵעֲלִיּוֹתָיו, מִפְּרִי מַעֲשֶׂיךָ תִּשְׂבַּע הָאָרֶץ:\nמַצְמִיחַ חָצִיר לַבְּהֵמָה וְעֵשֶׂב לַעֲבֹדַת הָאָדָם, לְהוֹצִיא לֶחֶם מִן הָאָרֶץ:\nוְיַיִן יְשַׂמַּח לְבַב אֱנוֹשׁ, לְהַצְהִיל פָּנִים מִשָּׁמֶן, וְלֶחֶם לְבַב אֱנוֹשׁ יִסְעָד:\nיִשְׂבְּעוּ עֲצֵי יהוה, אַרְזֵי לְבָנוֹן אֲשֶׁר נָטָע:\nאֲשֶׁר שָׁם צִפֳּרִים יְקַנֵּנוּ, חֲסִידָה בְּרוֹשִׁים בֵּיתָהּ:\nהָרִים הַגְּבֹהִים לַיְּעֵלִים, סְלָעִים מַחְסֶה לַשְׁפַנִּים:\nעָשָׂה יָרֵחַ לְמוֹעֲדִים, שֶׁמֶשׁ יָדַע מְבוֹאוֹ:\nתָּשֶׁת חֹשֶׁךְ וִיהִי לָיְלָה, בּוֹ תִרְמֹשׂ כָּל חַיְתוֹ יָעַר:\nהַכְּפִירִים שֹׁאֲגִים לַטָּרֶף וּלְבַקֵּשׁ מֵאֵל אָכְלָם:\nתִּזְרַח הַשֶּׁמֶשׁ יֵאָסֵפוּן וְאֶל מְעוֹנֹתָם יִרְבָּצוּן:","cond":["rh"]},{"kind":"special","text":"יֵצֵא אָדָם לְפָעֳלוֹ וְלַעֲבֹדָתוֹ עֲדֵי עָרֶב:\nמָה רַבּוּ מַעֲשֶׂיךָ יהוה, כֻּלָּם בְּחָכְמָה עָשִׂיתָ, מָלְאָה הָאָרֶץ קִנְיָנֶךָ:\nזֶה הַיָּם גָּדוֹל וּרְחַב יָדָיִם, שָׁם רֶמֶשׂ וְאֵין מִסְפָּר, חַיּוֹת קְטַנּוֹת עִם גְּדֹלוֹת:\nשָׁם אֳנִיּוֹת יְהַלֵּכוּן, לִוְיָתָן זֶה יָצַרְתָּ לְשַׂחֶק בּוֹ:\nכֻּלָּם אֵלֶיךָ יְשַׂבֵּרוּן לָתֵת אָכְלָם בְּעִתּוֹ:\nתִּתֵּן לָהֶם יִלְקֹטוּן, תִּפְתַּח יָדְךָ יִשְׂבְּעוּן טוֹב:\nתַּסְתִּיר פָּנֶיךָ יִבָּהֵלוּן, תֹּסֵף רוּחָם יִגְוָעוּן וְאֶל עֲפָרָם יְשׁוּבוּן:\nתְּשַׁלַּח רוּחֲךָ יִבָּרֵאוּן וּתְחַדֵּשׁ פְּנֵי אֲדָמָה:\nיְהִי כְבוֹד יהוה לְעוֹלָם, יִשְׂמַח יהוה בְּמַעֲשָׂיו:\nהַמַּבִּיט לָאָרֶץ וַתִּרְעָד, יִגַּע בֶּהָרִים וְיֶעֱשָׁנוּ:\nאָשִׁירָה לַיהוה בְּחַיָּי, אֲזַמְּרָה לֵאלֹהַי בְּעוֹדִי:\nיֶעֱרַב עָלָיו שִׂיחִי, אָנֹכִי אֶשְׂמַח בַּיהוה:\nיִתַּמּוּ חַטָּאִים מִן הָאָרֶץ וּרְשָׁעִים עוֹד אֵינָם, בָּרְכִי נַפְשִׁי אֶת יהוה, הַלְלוּיָהּ:","cond":["rh"]},{"kind":"instruction","text":"לפני התפלה יאמר:","cond":[]},{"kind":"text","text":"לְשֵׁם יִחוּד קֻדְשָׁא בְרִיךְ הוּא וּשְׁכִינְתֵּהּ, בִּדְחִילוּ וּרְחִימוּ, וּרְחִימוּ וּדְחִילוּ, לְיַחֲדָא שֵׁם אוֹת י' וְאוֹת ה' בְּשֵׁם אוֹת ו' וְאוֹת ה' בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל יִשְׂרָאֵל, לַאֲקָמָא שְׁכִינְתָּא מִעַפְרָא וּלְעִלּוּי שְׁכִינַת עֻזֵּנוּ, הִנֵּה אֲנַחְנוּ בָּאִים לְהִתְפַּלֵּל תְּפִלַּת עַרְבִית שֶׁתִּקֵּן יַעֲקֹב אָבִינוּ עָלָיו הַשָּׁלוֹם, עִם כָּל הַמִּצְוׂת הַכְּלוּלוֹת בָּהּ, לְתַקֵּן אֶת שָׁרְשָׁהּ בְּמָקוֹם עֶלְיוֹן, לַעֲשׂוֹת נַחַת רוּחַ לְיוֹצְרֵנוּ, וְלַעֲשׂוֹת רְצוֹן בּוֹרְאֵנוּ. וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ: וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ:\nיהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה: יהוה צְבָאוֹת אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":[]},{"kind":"instruction","text":"חצי קדיש","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית, וְהִרְבָּה לְהָשִׁיב אַפּוֹ וְלֹא יָעִיר כָּל חֲמָתוֹ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":[]},{"kind":"instruction","text":"חזן:","cond":[]},{"kind":"text","text":"בָּרְכוּ אֶת יהוה הַמְבֹרָךְ.","cond":[]},{"kind":"instruction","text":"קהל וחזן:","cond":[]},{"kind":"text","text":"בָּרוּךְ יהוה הַמְבֹרָךְ לְעוֹלָם וָעֶד.","cond":[]},{"kind":"instruction","text":"הברכות שלפני קריאת שמע","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר בִּדְבָרוֹ מַעֲרִיב עֲרָבִים בְּחָכְמָה, פּוֹתֵחַ שְׁעָרִים בִּתְבוּנָה, מְשַׁנֶּה עִתִּים וּמַחֲלִיף אֶת הַזְּמַנִּים, וּמְסַדֵּר אֶת הַכּוֹכָבִים בְּמִשְׁמְרוֹתֵיהֶם בָּרָקִיעַ כִּרְצוֹנוֹ, בּוֹרֵא יוֹמָם וָלָיְלָה, גּוֹלֵל אוֹר מִפְּנֵי חֹשֶׁךְ וְחֹשֶׁךְ מִפְּנֵי אוֹר, הַמַּעֲבִיר יוֹם וּמֵבִיא לָיְלָה, וּמַבְדִּיל בֵּין יוֹם וּבֵין לָיְלָה, יהוה צְבָאוֹת שְׁמוֹ. בָּרוּךְ אַתָּה יהוה, הַמַּעֲרִיב עֲרָבִים.\n\nאַהֲבַת עוֹלָם בֵּית יִשְׂרָאֵל עַמְּךָ אָהַבְתָּ, תּוֹרָה וּמִצְוׂת חֻקִּים וּמִשְׁפָּטִים אוֹתָנוּ לִמַּדְתָּ, עַל כֵּן יהוה אֱלֹהֵינוּ, בְּשָׁכְבֵנוּ וּבְקוּמֵנוּ נָשִׂיחַ בְּחֻקֶּיךָ, וְנִשְׂמַח וְנַעֲלֹז בְּדִבְרֵי תַלְמוּד תּוֹרָתֶךָ וּמִצְוׂתֶיךָ וְחֻקֹּתֶיךָ לְעוֹלָם וָעֶד, כִּי הֵם חַיֵּינוּ וְאֹרֶךְ יָמֵינוּ, וּבָהֶם נֶהְגֶּה יוֹמָם וָלָיְלָה. וְאַהֲבָתְךָ לֹא תָסוּר מִמֶּנּוּ לְעוֹלָמִים. בָּרוּךְ אַתָּה יהוה, אוֹהֵב אֶת עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"header","text":"קריאת שמע","cond":[]},{"kind":"instruction","text":"קריאת שמע","cond":[]},{"kind":"text","text":"שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:","cond":[]},{"kind":"instruction","text":"בלחש:","cond":[]},{"kind":"text","text":"בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד.\n\nוְאָהַבְתָּ אֵת יהוה אֱלֹהֶיךָ, בְּכָל לְבָבְךָ וּבְכָל נַפְשְׁךָ וּבְכָל מְאֹדֶךָ: וְהָיוּ הַדְּבָרִים הָאֵלֶּה אֲשֶׁר אָנֹכִי מְצַוְּךָ הַיּוֹם, עַל לְבָבֶךָ: וְשִׁנַּנְתָּם לְבָנֶיךָ וְדִבַּרְתָּ בָּם, בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ: וּקְשַׁרְתָּם לְאוֹת עַל יָדֶךָ, וְהָיוּ לְטֹטָפֹת בֵּין עֵינֶיךָ: וּכְתַבְתָּם עַל מְזֻזוֹת בֵּיתֶךָ וּבִשְׁעָרֶיךָ:","cond":[]},{"kind":"text","text":"וְהָיָה אִם שָׁמֹעַ תִּשְׁמְעוּ אֶל מִצְוׂתַי, אֲשֶׁר אָנֹכִי מְצַוֶּה אֶתְכֶם הַיּוֹם, לְאַהֲבָה אֶת יהוה אֱלֹהֵיכֶם וּלְעָבְדוֹ, בְּכָל לְבַבְכֶם וּבְכָל נַפְשְׁכֶם: וְנָתַתִּי מְטַר אַרְצְכֶם בְּעִתּוֹ, יוֹרֶה וּמַלְקוֹשׁ, וְאָסַפְתָּ דְגָנֶךָ וְתִירֹשְׁךָ וְיִצְהָרֶךָ: וְנָתַתִּי עֵשֶׂב בְּשָׂדְךָ לִבְהֶמְתֶּךָ, וְאָכַלְתָּ וְשָׂבָעְתָּ: הִשָּׁמְרוּ לָכֶם פֶּן יִפְתֶּה לְבַבְכֶם, וְסַרְתֶּם וַעֲבַדְתֶּם אֱלֹהִים אֲחֵרִים וְהִשְׁתַּחֲוִיתֶם לָהֶם: וְחָרָה אַף יהוה בָּכֶם, וְעָצַר אֶת הַשָּׁמַיִם וְלֹא יִהְיֶה מָטָר, וְהָאֲדָמָה לֹא תִתֵּן אֶת יְבוּלָהּ, וַאֲבַדְתֶּם מְהֵרָה מֵעַל הָאָרֶץ הַטֹּבָה אֲשֶׁר יהוה נֹתֵן לָכֶם: וְשַׂמְתֶּם אֶת דְּבָרַי אֵלֶּה עַל לְבַבְכֶם וְעַל נַפְשְׁכֶם, וּקְשַׁרְתֶּם אֹתָם לְאוֹת עַל יֶדְכֶם וְהָיוּ לְטוֹטָפֹת בֵּין עֵינֵיכֶם: וְלִמַּדְתֶּם אֹתָם אֶת בְּנֵיכֶם לְדַבֵּר בָּם, בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ: וּכְתַבְתָּם עַל מְזוּזוֹת בֵּיתֶךָ וּבִשְׁעָרֶיךָ: לְמַעַן יִרְבּוּ יְמֵיכֶם וִימֵי בְנֵיכֶם עַל הָאֲדָמָה אֲשֶׁר נִשְׁבַּע יהוה לַאֲבֹתֵיכֶם לָתֵת לָהֶם, כִּימֵי הַשָּׁמַיִם עַל הָאָרֶץ:","cond":[]},{"kind":"text","text":"וַיֹּאמֶר יהוה אֶל מֹשֶׁה לֵּאמֹר: דַּבֵּר אֶל בְּנֵי יִשְׂרָאֵל וְאָמַרְתָּ אֲלֵהֶם, וְעָשׂוּ לָהֶם צִיצִת עַל כַּנְפֵי בִגְדֵיהֶם לְדֹרֹתָם, וְנָתְנוּ עַל צִיצִת הַכָּנָף פְּתִיל תְּכֵלֶת: וְהָיָה לָכֶם לְצִיצִת, וּרְאִיתֶם אֹתוֹ, וּזְכַרְתֶּם אֶת כָּל מִצְוׂת יהוה וַעֲשִׂיתֶם אֹתָם, וְלֹא תָתֻרוּ אַחֲרֵי לְבַבְכֶם וְאַחֲרֵי עֵינֵיכֶם אֲשֶׁר אַתֶּם זֹנִים אַחֲרֵיהֶם: לְמַעַן תִּזְכְּרוּ וַעֲשִׂיתֶם אֶת כָּל מִצְוׂתָי, וִהְיִיתֶם קְדֹשִׁים לֵאלֹהֵיכֶם: אֲנִי יהוה אֱלֹהֵיכֶם אֲשֶׁר הוֹצֵאתִי אֶתְכֶם מֵאֶרֶץ מִצְרַיִם, לִהְיוֹת לָכֶם לֵאלֹהִים, אֲנִי יהוה אֱלֹהֵיכֶם:","cond":[]},{"kind":"text","text":"אֱמֶת","cond":[]},{"kind":"instruction","text":"יסיים \"אני ה' אלהיכם אמת\" עם שליח הציבור יחד, ומילת \"אמת\" יאמרו אותה הקהל בקול רם, ואחר כך ישתוק וישמע משליח הציבור כשחוזר ואומר \"ה' אלהיכם אמת\" ויכוון לצאת ידי חובה באמירתו של שליח הציבור, ושליח הציבור יכוון אף הוא להוציא את הקהל ידי חובה. והקורא קריאת שמע ביחידות או שלא הספיק לסיים עם שליח הציבור, יחזור לומר \"ה' אלהיכם אמת\" כדי להשלים לרמ\"ח תיבות.\n\nשליח הציבור חוזר ואומר:","cond":[]},{"kind":"text","text":"יהוה אֱלֹהֵיכֶם: אֱמֶת","cond":[]},{"kind":"instruction","text":"הברכות שאחרי קריאת שמע","cond":[]},{"kind":"text","text":"וֶאֱמוּנָה כָּל זֹאת וְקַיָּם עָלֵינוּ, כִּי הוּא יהוה אֱלֹהֵינוּ וְאֵין זוּלָתוֹ, וַאֲנַחְנוּ יִשׂרָאֵל עַמּוֹ. הַפּוֹדֵנוּ מִיַּד מְלָכִים, הַגּוֹאֲלֵנוּ מַלְכֵּנוּ מִכַּף כָּל הֶעָרִיצִים, הָאֵל הַנִּפְרָע לָנוּ מִצָּרֵינוּ, הַמְשַׁלֵּם גְּמוּל לְכָל אוֹיְבֵי נַפְשֵׁנוּ. הַשָּׂם נַפְשֵׁנוּ בַּחַיִּים, וְלֹא נָתַן לַמּוֹט רַגְלֵנוּ. הַמַּדְרִיכֵנוּ עַל בָּמוֹת אוֹיְבֵינוּ, וַיָּרֶם קַרְנֵנוּ עַל כָּל שׂוֹנְאֵינוּ. הָאֵל הָעוֹשֶׂה לָּנוּ נְקָמָה בְּפַרְעה, בְּאוֹתוֹת וּבְמוֹפְתִים בְּאַדְמַת בְּנֵי חָם, הַמַּכֶּה בְעֶבְרָתוֹ כָּל בְּכוֹרֵי מִצְרָיִם, וַיּוֹצִיא אֶת עַמּוֹ יִשְׂרָאֵל מִתּוֹכָם לְחֵרוּת עוֹלָם. הַמַּעֲבִיר בָּנָיו בֵּין גִּזְרֵי יַם סוּף, וְאֶת רוֹדְפֵיהֶם וְאֶת שׂוֹנְאֵיהֶם בִּתְהוֹמוֹת טִבַּע. רָאוּ בָנִים אֶת גְּבוּרָתוֹ, שִׁבְּחוּ וְהוֹדוּ לִשְׁמוֹ. וּמַלְכוּתוֹ, בְּרָצון קִבְּלוּ עֲלֵיהֶם, משֶׁה וּבְנֵי יִשְׂרָאֵל לְךָ עָנוּ שִׁירָה בְּשִׂמְחָה רַבָּה, וְאָמְרוּ כֻלָּם:\n\nמִי כָמֹכָה בָּאֵלִם יהוה, מִי כָּמֹכָה נֶאְדָּר בַּקֹּדֶשׁ, נוֹרָא תְהִלֹּת עֹשֵׂה פֶלֶא:\n\nמַלְכוּתְךָ יהוה אֱלֹהֵינוּ רָאוּ בָנֶיךָ עַל הַיָּם, יַחַד כֻּלָּם הוֹדוּ וְהִמְלִיכוּ וְאָמְרוּ:\n\nיהוה יִמְלֹךְ לְעֹלָם וָעֶד:\n\nוְנֶאֱמַר: כִּי פָדָה יהוה אֶת יַעֲקֹב וּגְאָלוֹ מִיַּד חָזָק מִמֶּנּוּ: בָּרוּךְ אַתָּה יהוה, גָּאַל יִשְׂרָאֵל.\n\n\nהַשְׁכִּיבֵנוּ אָבִינוּ לְשָׁלוֹם, וְהַעֲמִידֵנוּ מַלְכֵּנוּ לְחַיִּים טוֹבִים וּלְשָׁלוֹם, וּפְרֹשׂ עָלֵינוּ סֻכַּת שְׁלוֹמֶךָ, וְתַקְּנֵנוּ מַלְכֵּנוּ בְּעֵצָה טוֹבָה מִלְּפָנֶיךָ, וְהוֹשִׁיעֵנוּ מְהֵרָה לְמַעַן שְׁמֶךָ, וְהָגֵן בַּעֲדֵנוּ, וְהָסֵר מֵעָלֵינוּ מַכַּת אוֹיֵב, דֶּבֶר, חֶרֶב, חֹלִי, צָרָה, רָעָה, רָעָב וְיָגוֹן וּמַשְׁחִית וּמַגֵּפָה. שְׁבֹר וְהָסֵר הַשָּׂטָן מִלְּפָנֵינוּ וּמֵאַחֲרֵינוּ, וּבְצֵל כְּנָפֶיךָ תַּסְתִּירֵנוּ. וּשְׁמוֹר צֵאתֵנוּ וּבוֹאֵנוּ לְחַיִּים טוֹבִים וּלְשָׁלוֹם מֵעַתָּה וְעַד עוֹלָם, כִּי אֵל שׁוֹמְרֵנוּ וּמַצִּילֵנוּ אַתָּה מִכָּל דָּבָר רָע וּמִפַּחַד לָיְלָה. בָּרוּךְ אַתָּה יהוה, שׁוֹמֵר אֶת עַמּוֹ יִשְׂרָאֵל לָעַד. אָמֵן.","cond":[]},{"kind":"instruction","text":"חצי קדיש","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"header","text":"עמידה","cond":[]},{"kind":"instruction","text":"תפילת עמידה","cond":[]},{"kind":"text","text":"אֲדֹנָי, שְׂפָתַי תִּפְתָּח, וּפִי יַגִּיד תְּהִלָּתֶךָ:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יְהֹוָה, אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק וֵאלֹהֵי יַעֲקֹב, הָאֵל הַגָּדוֹל, הַגִּבּוֹר וְהַנּוֹרָא, אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, קוֹנֵה הַכֹּל וְזוֹכֵר חַסְדֵי אָבוֹת וּמֵבִיא גּוֹאֵל לִבְנֵי בְנֵיהֶם לְמַעַן שְׁמוֹ בְּאַהֲבָה.","cond":[]},{"kind":"special","text":"זָכְרֵנוּ לְחַיִּים, מֶלֶךְ חָפֵץ בַּחַיִּים, כָּתְבֵנוּ בְּסֵפֶר חַיִּים, לְמַעַנְךָ אֱלֹהִים חַיִּים.","cond":["ayt"]},{"kind":"text","text":"מֶלֶךְ עוֹזֵר וּמוֹשִׁיעַ וּמָגֵן. בָּרוּךְ אַתָּה יַהַוַהַ, מָגֵן אַבְרָהָם.","cond":[]},{"kind":"text","text":"אַתָּה גִּבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֵּה מֵתִים אַתָּה, רַב לְהוֹשִׁיעַ,","cond":[]},{"kind":"summer","text":"מוֹרִיד הַטָּל,","cond":["summerTal"]},{"kind":"winter","text":"מַשִּׁיב הָרוּחַ וּמוֹרִיד הַגֶּשֶׁם,","cond":["winterTal"]},{"kind":"text","text":"מְכַלְכֵּל חַיִּים בְּחֶסֶד, מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים, סוֹמֵךְ נוֹפְלִים וְרוֹפֵא חוֹלִים, וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמוּנָתוֹ לִישֵׁנֵי עָפָר. מי כָמוֹךָ בַּעַל גְּבוּרוֹת וּמִי דוֹמֶה לָךְ, מֶלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִיחַ יְשׁוּעָה.","cond":[]},{"kind":"special","text":"מִי כָמוֹךָ אַב הָרַחֲמָן, זוֹכֵר יְצוּרָיו בְּרַחֲמִים לְחַיִּים.","cond":["ayt"]},{"kind":"text","text":"וְנֶאֱמָן אַתָּה לְהַחֲיוֹת מֵתִים. בָּרוּךְ אַתָּה יֵהֵוֵהֵ, מְחַיֵּה הַמֵּתִים.","cond":[]},{"kind":"text","text":"אַתָּה קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ, וּקְדוֹשִׁים בְּכָל-יוֹם יְהַלְלוּךָ סֶּלָה.","cond":[]},{"kind":"special","text":"בָּרוּךְ אַתָּה יֹהֵוָה, הַמֶּלֶךְ הַקָּדוֹשׁ.","cond":["ayt"]},{"kind":"text","text":"בּרוּךְ אַתָּה יֹהֵוָה, הָאֵל הַקָּדוֹשׁ.","cond":["noayt"]},{"kind":"text","text":"אַתָּה חוֹנֵן לְאָדָם דַּעַת וּמְלַמֵּד לֶאֱנוֹשׁ בִּינָה.","cond":[]},{"kind":"special","text":"אַתָּה חוֹנַנְתָּנוּ יהוה אֱלֹהֵינוּ מַדָּע וְהַשְׂכֵּל, אַתָּה אָמַרְתָּ לְהַבְדִּיל בֵּין קֹדֶשׁ לְחֹל וּבֵין אוֹר לְחֹשֶׁךְ וּבֵין יִשְׂרָאֵל לָעַמִּים, וּבֵין יוֹם הַשְּׁבִיעִי לְשֵׁשֶׁת יְמֵי הַמַּעֲשֶׂה. כְּשֵׁם שֶׁהִבְדַּלְתָּנוּ יהוה אֱלֹהֵינוּ מֵעַמֵּי הָאֲרָצוֹת וּמִמִּשְׁפְּחוֹת הָאֲדָמָה, כָּךְ פְּדֵנוּ וְהַצִּילֵנוּ מִשָּׂטָן רָע וּמִפֶּגַע רָע, וּמִכָּל גְּזֵרוֹת קָשׁוֹת וְרָעוֹת הַמִּתְרַגְּשׁוֹת לָבֹא בָּעוֹלָם.","cond":["chonantanu"]},{"kind":"text","text":"וְחָנֵּנוּ מֵאִתְּךָ חָכְמָה בִּינָה וָדָעַת. בָּרוּךְ אַתָּה יַהַוַהַ חוֹנֵן הַדָּעַת.","cond":[]},{"kind":"text","text":"הֲשִׁיבֵנוּ אָבִינוּ לְתוֹרָתֶךָ, וְקָרְבֵנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶךָ, וְהַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ. בָּרוּךְ אַתָּה יֵהֵוֵהֵ, הָרוֹצֶה בִּתְשׁוּבָה.","cond":[]},{"kind":"text","text":"סְלַח לָנוּ אָבִינוּ כִּי חָטָאנוּ, מְחֹל לָנוּ מַלְכֵּנוּ כִּי פָשָׁעְנוּ, כִּי אֵל טוֹב וְסַלָּח אָתָּה. בָּרוּךְ אַתָּה יֶהֶוֶהֶ, חַנּוּן הַמַּרְבֶּה לִסְלֹחַ.","cond":[]},{"kind":"text","text":"רְאֵה נָא בְעָנְיֵנוּ וְרִיבָה רִיבֵנוּ, וּמַהֵר לְגָאֳלֵנוּ גְאֻלָּה שְׁלֵמָה לְמַעַן שְׁמֶךָ, כִּי אֵל גּוֹאֵל חָזָק אָתָּה. בָּרוּךְ אַתָּה יְהְוְהְ, גוֹאֵל יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"רְפָאֵנוּ יְהֹוָה וְנֵרָפֵא, הוֹשִׁיעֵנוּ וְנִוָּשֵׁעָה כִּי תְהִלָּתֵנוּ אָתָּה, וְהַעֲלֵה אֲרוּכָה וּמַרְפֵּא לְכָל-תַּחֲלוּאֵינוּ וּלְכָל-מַכְאוֹבֵינוּ וּלְכָל-מַכּוֹתֵינוּ.","cond":[]},{"kind":"special","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁתִּשְׁלַח מְהֵרָה רְפוּאָה שְׁלֵמָה מִן הַשָּׁמַיִם, רְפוּאַת הַנֶּפֶשׁ וּרְפוּאַת הַגּוּף לַחוֹלֶה (לנקבה: לַחוֹלָה, לרבים: לַחוֹלִים, לרבות: לַחוֹלוֹת):\n:=:=\nבְּתוֹךְ שְׁאָר חוֹלֵי יִשְׂרָאֵל.","cond":["doctor"]},{"kind":"text","text":"כִּי אֵל רוֹפֵא רַחֲמָן וְנֶאֱמָן אָתָּה. בָּרוּךְ אַתָּה יֹהֹוׂהֹ, רוֹפֵא חוֹלֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"summer","text":"בָּרְכֵנוּ יְהֹוָה אֱלֹהֵינוּ בְּכָל מַעֲשֵׂי יָדֵינוּ, וּבָרֵךְ שְׁנָתֵנוּ בְּטַלְלֵי רָצוֹן בְּרָכָה וּנְדָבָה, וּתְהִי אַחֲרִיתָהּ חַיִּים וְשָׂבָע וְשָׁלוֹם כַּשָּׁנִים הַטּוֹבוֹת לִבְרָכָה. כִּי אֵל טוֹב וּמֵטִיב אַתָּה וּמְבָרֵךְ הַשָּׁנִים. בָּרוּךְ אַתָּה יִהִוִהִ, מְבָרֵךְ הַשָּׁנִים.","cond":["summerBracha"]},{"kind":"winter","text":"בָּרֵךְ עָלֵינוּ יְהֹוָה אֱלֹהֵינוּ אֶת הַשָּׁנָה הַזֹּאת וְאֶת כָּל מִינֵי תְּבוּאָתָהּ לְטוֹבָה, וְתֵן טַל וּמָטָר לִבְרָכָה עַל כָּל פְּנֵי הָאֲדָמָה, וְרַוֵּה פְּנֵי תֵבֵל וְשַׂבַּע אֶת הָעוֹלָם כֻּלּוֹ מִטּוּבָךְ, וּמַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ וּמֵעֹשֶׁר מַתְּנוֹת יָדֶיךָ. שָׁמְרָה וְהַצִּילָה שָׁנָה זוֹ מִכָּל דָּבָר רָע וּמִכָּל מִינֵי מַשְׁחִית וּמִכָּל מִינֵי פֻרְעָנוּת, וַעֲשֵׂה לָהּ תִּקְוָה טוֹבה וְאַחֲרִית שָׁלוֹם. חוּס וְרַחֵם עָלֶיהָ וְעַל כָּל תְּבוּאָתָהּ וּפֵירוֹתֶיהָ, וּבָרְכָהּ בְּגִשְׁמֵי רָצוֹן בְּרָכָה וּנְדָבָה, וּתְהִי אַחֲרִיתָהּ חַיִּים וְשָׂבָע וְשָׁלוֹם כַּשָּׁנִים הַטּוֹבוֹת לִבְרָכָה. כִּי אֵל טוֹב וּמֵטִיב אַתָּה וּמְבָרֵךְ הַשָּׁנִים. בָּרוּךְ אַתָּה יִהִוִהִ, מְבָרֵךְ הַשָּׁנִים.","cond":["winterBracha"]},{"kind":"text","text":"תְּקַע בְּשׁוֹפָר גָּדוֹל לְחֵרוּתֵנוּ, וְשָׂא נֵס לְקַבֵּץ גָּלֻיּוֹתֵינוּ, וְקַבְּצֵנוּ יַחַד מֵאַרְבַּע כַּנפוֹת הָאָרֶץ לְאַרְצֵנוּ. בָּרוּךְ אַתָּה יֻהֻוֻהֻ, מְקַבֵּץ נִדְחֵי עַמּוֹ יִשְׂרָאֵל.","cond":[]},{"kind":"text","text":"הָשִׁיבָה שׁוֹפְטֵינוּ כְּבָרִאשׁוֹנָה, וְיוֹעֲצֵינוּ כְּבַתְּחִלָּה, וְהָסֵר מִמֶּנוּ יָגוֹן וַאֲנָחָה, וּמְלֹךְ עָלֵינוּ מְהֵרָה אַתָּה יְהֹוָה לְבַדְּךָ, בְּחֶסֶד וּבְרַחֲמִים, בְּצֶדֶק וּבְמִשְׁפָּט.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יוּהוּווּהוּ, מֶלֶךְ אוֹהֵב צְדָקָה וּמִשְׁפָּט.","cond":["noAyt"]},{"kind":"special","text":"בָּרוּךְ אַתָּה יוּהוּווּהוּ, הַמֶּלֶךְ הַמִּשְׁפָּט.","cond":["ayt"]},{"kind":"text","text":"לַמִּינִים וְלַמַּלְשִׁינִים אַל תְּהִי תִקְוָה, וְכָל הַזֵּדִים כְּרֶגַע יֹאבֵדוּ, וְכָל אוֹיְבֶיךָ וְכָל שׂוֹנְאֶיךָ מְהֵרָה יִכָּרֵתוּ, וּמַלְכוּת הָרִשְׁעָה מְהֵרָה תְעַקֵּר וּתְשַׁבֵּר וּתְכַלֵּם וְתַכְנִיעֵם בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יָהָוָהָ, שׁוֹבֵר אוֹיְבִים וּמַכְנִיעַ זֵדִים.","cond":[]},{"kind":"text","text":"עַל הַצַּדִּיקִים וְעַל הַחֲסִידִים וְעַל שְׁאֵרִית עַמְּךָ בֵּית יִשְׂרָאֵל וְעַל זִקְנֵיהֶם וְעַל פְּלֵטַת בֵּית סוֹפְרֵיהֶם וְעַל גֵּרֵי הַצֶּדֶק וְעָלֵינוּ, יֶהֱמוּ נָא רַחֲמֶיךָ יְהֹוָה אֱלֹהֵינוּ, וְתֵן שָׂכָר טוֹב לְכָל הַבּוֹטְחִים בְּשִׁמְךָ בֶאֱמֶת, וְשִׂים חֶלְקֵנוּ עִמָּהֶם, וּלְעוֹלָם לֹא נֵבוֹשׁ כִּי בְךָ בָטַחְנוּ, וְעַל חַסְדְּךָ הַגָּדוֹל בֶּאֱמֶת נִשְׁעָנְנוּ. בָּרוּךְ אַתָּה יוּהוּווּהוּ, מִשְׁעָן וּמִבְטָח לַצַּדִּיקִים.","cond":[]},{"kind":"text","text":"תִּשְׁכּוֹן בְּתוֹךְ יְרוּשָׁלַיִם עִירְךָ כַּאֲשֶׁר דִּבַּרְתָּ, וְכִסֵּא דָוִד עַבְדְּךָ מְהֵרָה בְתוֹכָהּ תָּכִין, וּבְנֵה אוֹתָהּ בִּנְיַן עוֹלָם בִּמְהֵרָה בְיָמֵינוּ.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יֻהֻוֻהֻ, בּוֹנֵה יְרוּשָׁלָיִם.","cond":["noTishaaBeav"]},{"kind":"special","text":"נַחֵם יהוה אֱלֹהֵינוּ אֶת אֲבֵלֵי צִיּוֹן וְאֶת אֲבֵלֵי יְרוּשָׁלַיִם, וְאֶת הָעִיר הַחֲרֵבָה וְהַבְּזוּיָה וְהַשוֹמֵמָה, מִבְּלִי בָנֶיהָ הִיא יוֹשֶׁבֶת, וְרֹאשָׁהּ חָפוּי כְּאִשָּׁה עֲקָרָה שֶׁלֹּא יָלָדָה. וַיְבַלְּעוּהָ לִגְיוֹנִים וַיִּירָשׁוּהָ, וַיַטִּילוּ אֶת עַמְּךָ יִשְׂרָאֵל לַחֶרֶב, וַיַּהַרְגוּ בְזָדוֹן חֲסִידָי עֶלְיוֹן. עַל כֵּן צִיּוֹן בְּמֶרֶר תִּבְכֶּה וִירוּשָׁלַיִם תִּתֵּן קוֹלָהּ. לִבִּי לִבִּי עַל חַלְלֵיהֶם, מֵעַי מֵעַי עַל הֲרוּגֵיהֶם. כִּי אַתָּה יהוה בָּאֵשׁ הִצַּתָּהּ, וּבָאֵשׁ אַתָּה עָתִיד לִבְנוֹתָהּ, כַּכָּתוּב: וַאֲנִי אֶהְיֶה לָהּ נְאֻם יְהוה חוֹמַת אֵשׁ סָבִיב, וּלְכָבוֹד אֶהְיֶה בְתוֹכָהּ: בָּרוּךְ אַתָּה יהוה, מְנַחֵם צִיּוֹן בְּבִנְיַן יְרוּשָׁלַיִם.","cond":["tishaaBeav"]},{"kind":"text","text":"אֶת צֶמַח דָּוִד עַבְדְּךָ מְהֵרָה תַצְמִיחַ, וְקַרְנוֹ תָרוּם בִּישׁוּעָתֶךָ. כִּי לִישׁוּעָתְךָ קִוִּינוּ וְצִפִּינוּ כָּל הַיּוֹם. בָּרוּךְ אַתָּה יִהִוִהִ, מַצְמִיחַ קֶרֶן יְשׁוּעָה.","cond":[]},{"kind":"text","text":"שְׁמַע קוֹלֵנוּ יְהֹוָה אֱלֹהֵינוּ, אָב הָרַחֲמָן רַחֵם עָלֵינוּ, וְקַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ, כִּי אֵל שׁוֹמֵעַ תְּפִלּוֹת וְתַחֲנוּנִים אָתָּה, וּמִלְּפָנֶיךָ מַלְכֵּנוּ, רֵיקָם אַל תְּשִׁיבֵנוּ. חָנֵּנוּ וַעֲנֵנוּ וּשְׁמַע תְּפִלָּתֵנוּ.","cond":[]},{"kind":"instruction","text":"בתענית ציבור יאמר היחיד \"עננו\".","cond":["tishaaBeav"]},{"kind":"special","text":"עֲנֵנוּ אָבִינוּ עֲנֵנוּ בְּיוֹם צוֹם הַתַּעֲנִית הַזֶּה, כִּי בְצָרָה גְדוֹלָה אֲנָחְנוּ. אַל תֵּפֶן לְרִשְׁעֵנוּ, וְאַל תִּתְעַלַּם מַלְכֵּנוּ מִבַּקָּשָׁתֵנוּ, הֱיֵה נָא קָרוֹב לְשַׁוְעָתֵנוּ. טֶרֶם נִקְרָא אֵלֶיךָ אַתָּה תַעֲנֶה, נְדַבֵּר וְאַתָּה תִשְׁמַע, כַּדָּבָר שֶׁנֶּאֱמַר: וְהָיָה טֶרֶם יִקְרָאוּ וַאֲנִי אֶעֱנֶה, עוֹד הֵם מְדַבְּרִים וַאֲנִי אֶשְׁמָע: כִּי אַתָּה יהוה פּוֹדֶה וּמַצִּיל וְעוֹנֶה וּמְרַחֵם בְּכָל עֵת צָרָה וְצוּקָה.","cond":["tishaaBeav"]},{"kind":"text","text":"כִּי אַתָּה שׁוֹמֵעַ תְּפִלַּת כָּל פֶּה. בָּרוּךְ אַתָּה יהוה, שׁוֹמֵעַ תְּפִלָּה.","cond":[]},{"kind":"text","text":"רְצֵה יְהֹוָה אֱלֹהֵינוּ בְּעַמְּךָ יִשְׂרָאֵל, וּלִתְפִלָּתָם שְׁעֵה, וְהָשֵׁב הָעֲבוֹדָה לִדְבִיר בֵּיתֶךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם מְהֵרָה בְאַהֲבָה תְּקַבֵּל בְּרָצוֹן, וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּךָ.","cond":[]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, זִכְרוֹן יְרוּשָׁלַיִם עִירָךְ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן לְחֶסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["rh"]},{"kind":"special","text":"רֹאשׁ הַחֹדֶשׁ הַזֶּה,","cond":["rh"]},{"kind":"special","text":"לְרַחֵם בּוֹ עָלֵינוּ וּלְהוֹשִׁיעֵנוּ. זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. בִּדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וַחֲמוֹל וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["rh"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, זִכְרוֹן יְרוּשָׁלַיִם עִירָךְ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן לְחֶסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["sucot"]},{"kind":"special","text":"חַג הַסֻּכּוֹת הַזֶּה, בְּיוֹם מִקְרָא קֹדֶשׁ הַזֶּה,","cond":["sucot"]},{"kind":"special","text":"לְרַחֵם בּוֹ עָלֵינוּ וּלְהוֹשִׁיעֵנוּ. זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. בִּדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וַחֲמוֹל וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["sucot"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, זִכְרוֹן יְרוּשָׁלַיִם עִירָךְ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן לְחֶסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["pesach"]},{"kind":"special","text":"חַג הַמַּצּוֹת הַזֶּה, בְּיוֹם מִקְרָא קֹדֶשׁ הַזֶּה,","cond":["pesach"]},{"kind":"special","text":"לְרַחֵם בּוֹ עָלֵינוּ וּלְהוֹשִׁיעֵנוּ. זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. בִּדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וַחֲמוֹל וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["pesach"]},{"kind":"text","text":"וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים תַּחְפֹּץ בָּנוּ וְתִרְצֵנוּ, וְתֶחֱזֶינָה עֵינֵינוּ בְּשׁוּבְךָ לְצִיּוֹן בְּרַחֲמִים. בָּרוּךְ אַתָּה יִהִוִהִ, הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן.","cond":[]},{"kind":"text","text":"מוֹדִים אֲנַחְנוּ לָךְ, שֶׁאַתָּה הוּא יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ לְעוֹלָם וָעֶד, צוּרֵנוּ צוּר חַיֵּינוּ וּמָגֵן יִשְׁעֵנוּ אַתָּה הוּא לְדֹר וָדֹר. נוֹדֶה לְּךָ וּנְסַפֵּר תְּהִלָּתֶךָ, עַל חַיֵּינוּ הַמְּסוּרִים בְּיָדֶךָ, וְעַל נִשְׁמוֹתֵינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּיךָ שֶׁבְּכָל יוֹם עִמָּנוּ, וְעַל נִפְלְאוֹתֶיךָ וְטוֹבוֹתֶיךָ שֶׁבְּכָל עֵת, עֶרֶב וָבֹקֶר וְצָהֳרָיִם. הַטּוֹב, כִּי לֹא כָלוּ רַחֲמֶיךָ, הַמְרַחֵם, כִּי לֹא תַמּוּ חֲסָדֶיךָ, כִּי מֵעוֹלָם קִוִּינוּ לָךְ.","cond":[]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת, שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה, בִּימֵי מַתִּתְיָה בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְשַׁכְּחָם תּוֹרָתָךְ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנָךְ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וּטְמֵאִים בְּיַד טְהוֹרִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, לְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמָךְ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כָּךְ בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ בְּהַלֵּל גָּמוּר וּבְהוֹדָאָה, וְעָשִׂיתָ עִמָּהֶם נִסִּים וְנִפְלָאוֹת, וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל, סֶלָה.","cond":["chanuka"]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת, שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה, בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים, בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ, וְעָשִׂיתָ עִמָּהֶם נִסִּים וְנִפְלָאוֹת, וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל, סֶלָה.","cond":["purim"]},{"kind":"text","text":"וְעַל כֻּלָּם יִתְבָּרַךְ וְיִתְרוֹמַם וְיִתְנַשֵּׂא תָמִיד, שִׁמְךָ מַלְכֵּנוּ, לְעוֹלָם וָעֶד. וְכָל הַחַיִּים יוֹדוּךָ סֶּלָה.","cond":[]},{"kind":"special","text":"וּכְתֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶךָ.","cond":["ayt"]},{"kind":"text","text":"וִיהַלְלוּ וִיבָרְכוּ אֶת שִׁמְךָ הַגָּדוֹל, בֶּאֱמֶת, לְעוֹלָם כִּי טוֹב, הָאֵל יְשׁוּעָתֵנוּ וְעֶזְרָתֵנוּ סֶלָה, הָאֵל הַטּוֹב. בָּרוּךְ אַתָּה יֻהֻוֻהֻ, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת.","cond":[]},{"kind":"text","text":"שִׂים שָׁלוֹם טוֹבָה וּבְרָכָה, חַיִּים, חֵן וָחֶסֶד, צְדָקָה וְרַחֲמִים, עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל עַמֶּךָ. וּבָרְכֵנוּ אָבִינוּ, כֻּלָּנוּ כְאֶחָד בְּאוֹר פָּנֶיךָ, כִּי בְאוֹר פָּנֶיךָ נָתַתָּ לָּנוּ יְהֹוָה אֱלֹהֵינוּ, תּוֹרָה וְחַיִּים, אַהֲבָה וָחֶסֶד, צְדָקָה וְרַחֲמִים, בְּרָכָה וְשָׁלוֹם. וְטוֹב בְּעֵינֶיךָ לְבָרְכֵנוּ וּלְבָרֵךְ אֶת כָּל עַמְּךָ יִשְׂרָאֵל בְּרֹב עֹז וְשָׁלוֹם.","cond":[]},{"kind":"special","text":"וּבְסֵפֶר חֵיִּים, בְּרָכָה וְשָׁלוֹם, וּפַרְנָסָה טוֹבָה וִישׁוּעָה וְנֶחָמָה, וּגְזֵרוֹת טוֹבוֹת, נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ, אֲנַחְנוּ וְכָל עַמְּךָ יִשְׂרָאֵל, לְחַיִּים טוֹבִים וּלְשָׁלוֹם.","cond":["ayt"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יוּהוּווּהוּ, הַמְּבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם. אָמֵן.","cond":[]},{"kind":"text","text":"יִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:\nאֱלֹהַי, נְצֹר לְשׁוֹנִי מֵרָע, וּשְׂפָתַי מִדַּבֵּר מִרְמָה, וְלִמְקַלְלַי נַפְשִׁי תִדֹּם, וְנַפְשִׁי כֶּעָפָר לַכֹּל תִּהְיֶה. פְּתַח לִבִּי בְּתוֹרָתֶךָ, וְאַחֲרֵי מִצְוׂתֶיךָ תִּרְדֹּף נַפְשִׁי. וְכָל הַקָּמִים עָלַי לְרָעָה, מְהֵרָה הָפֵר עֲצָתָם וְקַלְקֵל מַחְשְבוֹתָם. (יִהְיוּ כְּמֹץ לִפְנֵי רוּחַ, וּמַלְאַךְ יהוה דּוֹחֶה.) עֲשֵׂה לְמַעַן שְׁמָךְ, עֲשֵׂה לְמַעַן יְמִינָךְ, עֲשֵׂה לְמַעַן תּוֹרָתָךְ, עֲשֵׂה לְמַעַן קְדֻשָּׁתָךְ, לְמַעַן יֵחָלְצוּן יְדִידֶיךָ. הוֹשִׁיעָה יְמִינְךָ וַעֲנֵנִי.\nיִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגוֹאֲלִי:","cond":[]},{"kind":"instruction","text":"יש נוהגים לומר כאן תחנונים, ויש אומרים תפילה זו:\nיְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁלֹּא תַעֲלֶה קִנְאַת אֲחֵרִים עָלַי וְלֹא קִנְאָתִי עַל אֲחֵרִים, וְשֶׁלֹּא אֶכְעוֹס הַיּוֹם וְשֶׁלֹּא אַכְעִיסֶך, וְתַצִּילֵנִי מִיֵּצֶר הָרָע, וְתֵן בְּלִבִּי הַכְנָעָה וַעֲנָוָה וְיִרְאַת חֵטְא. מַלְכֵּנוּ וֵאלֹהֵינוּ, יַחֵד שִׁמְךָ בְּעוֹלָמָךְ וּבְנֵה בֵיתָךְ, שַׁכְלֵל הֵיכָלָךְ וְקַבֵּץ גָּלֻיּוֹתֵינוּ, פְּדֵה צֹאנָךְ וְשַמַּח עֲדָתָךְ בִּמְהֵרָה בְיָמֵינוּ וְתֵן חֶלְקֵנוּ בְּתוֹרָתָךְ. אָמֵן.","cond":[]},{"kind":"text","text":"עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּבְנֶה בֵית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵינוּ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתָךְ לַעֲשׂוֹת חֻקֵּי רְצוֹנָךְ וּלְעָבְדָךְ בְּלֵבָב שָׁלֵם.","cond":[]},{"kind":"text","text":"יְהִי שֵׁם יהוה מְבֹרָךְ מֵעַתָּה וְעַד עוֹלָם: מִמִּזְרַח שֶׁמֶשׁ עַד מְבוֹאוֹ, מְהֻלָּל שֵׁם יהוה: רָם עַל כָּל גּוֹיִם יהוה, עַל הַשָּׁמַיִם כְּבוֹדוֹ: יהוה אֲדֹנֵינוּ, מָה אַדִּיר שִׁמְךָ בְּכָל הָאָרֶץ:","cond":[]},{"kind":"instruction","text":"חצי קדיש","cond":["em_kadosh"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["em_kadosh"]},{"kind":"header","text":"שובה","cond":["em_kadosh","sun"]},{"kind":"text","text":"הֲרֵינִי מֵכִין עַצְמִי לְקַבֵּל אוֹר תּוֹסֶפֶת קְדֻשַּׁת שַׁבָּת לִימֵי הַחוֹל, ואֶתְקַדֵּשׁ בּעֶזְרַת הַשֵּׁם יִתְבָּרַךְ בִּימֵי הַחֹל מִקְּדֻשַּׁת הַשַּׁבָּת, כּמוֹ שֶׁצִּוָּנוּ בְּתוֹרָתוֹ הַקְּדוֹשָׁה: \"והִתְקַדִּשְׁתֶּם וִהְיִיתֶם קְדֹשִׁים\". וִיהִי רָצוֹן מִלְּפָנֶיךָ, יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁיַּעֲלֶה לְפָנֶיךָ כְאִלּוּ כִּוַּנְתִּי בְּכָל הַכַּוָּנוֹת הָרְאוּיוֹת לכַוֵּן בָּזֶה.\n\nשׁוּבָה יהוה עַד מָתַי, וְהִנָּחֵם עַל עֲבָדֶיךָ: שַׂבְּעֵנוּ בַבֹּקֶר חַסְדֶּךָ, וּנְרַנְּנָה וְנִשְׂמְחָה בְּכָל יָמֵינוּ: שַׂמְּחֵנוּ כִּימות עִנִּיתָנוּ, שְׁנות רָאִינוּ רָעָה: יֵרָאֶה אֶל עֲבָדֶיךָ פָעֳלֶךָ, וַהֲדָרְךָ עַל בְּנֵיהֶם: וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ: יֹשֵׁב בְּסֵתֶר עֶלְיוֹן בְּצֵל שַׁדַּי יִתְלוֹנָן: אֹמַר לַיהוה מַחְסִי וּמְצוּדָתִי, אֱלֹהַי אֶבְטַח בּוֹ: כִּי הוּא יַצִּילְךָ מִפַּח יָקוּשׁ מִדֶּבֶר הַוּוֹת: בְּאֶבְרָתוֹ יָסֶךְ לָךְ וְתַחַת כְּנָפָיו תֶּחְסֶה, צִנָּה וְסֹחֵרָה אֲמִתּוֹ: לֹא תִירָא מִפַּחַד לָיְלָה, מֵחֵץ יָעוּף יוֹמָם: מִדֶּבֶר בָּאֹפֶל יַהֲלֹךְ, מִקֶּטֶב יָשׁוּד צָהֳרָיִם: יִפֹּל מִצִּדְּךָ אֶלֶף וּרְבָבָה מִימִינֶךָ, אֵלֶיךָ לֹא יִגָּשׁ: רַק בְּעֵינֶיךָ תַבִּיט, וְשִׁלֻּמַת רְשָׁעִים תִּרְאֶה: כִּי אַתָּה יהוה מַחְסִי, עֶלְיוֹן שַׂמְתָּ מְעוֹנֶךָ: לֹא תְאֻנֶּה אֵלֶיךָ רָעָה, וְנֶגַע לֹא יִקְרַב בְּאָהֳלֶךָ: כִּי מַלְאָכָיו יְצַוֶּה לָּךְ, לִשְׁמָרְךָ בְּכָל דְּרָכֶיךָ: עַל כַּפַּיִם יִשָּׂאוּנְךָ, פֶּן תִּגֹּף בָּאֶבֶן רַגְלֶךָ: עַל שַׁחַל וָפֶתֶן תִּדְרֹךְ, תִּרְמֹס כְּפִיר וְתַנִּין: כִּי בִי חָשַׁק וַאֲפַלְּטֵהוּ, אֲשַׂגְּבֵהוּ כִּי יָדַע שְׁמִי: יִקְרָאֵנִי וְאֶעֱנֵהוּ, עִמּוֹ אָנֹכִי בְצָרָה, אֲחַלְּצֵהוּ וַאֲכַבְּדֵהוּ: אֹרֶךְ יָמִים אַשְׂבִּיעֵהוּ, וְאַרְאֵהוּ בִּישׁוּעָתִי: אֹרֶךְ יָמִים אַשְׂבִּיעֵהוּ, וְאַרְאֵהוּ בִּישׁוּעָתִי:","cond":["em_kadosh","sun"]},{"kind":"header","text":"ואתה קדוש","cond":["em_kadosh"]},{"kind":"text","text":"וְאַתָּה קָדוֹשׁ יוֹשֵׁב תְּהִלּוֹת יִשְׂרָאֵל: וְקָרָא זֶה אֶל זֶה וְאָמַר: קָדוֹשׁ, קָדוֹשׁ, קָדוֹשׁ יהוה צְבָאוֹת, מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ: וּמְקַבְּלִין דֵּין מִן דֵּין וְאָמְרִין: קַדִּישׁ בִּשְׁמֵי מֵרוֹמַא עִלָאַה בֵּית שְׁכִינְתֵּהּ, קַדִּישׁ עַל אַרְעָא עוֹבַד גְּבוּרְתֵּהּ, קַדִּישׁ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא, יהוה צְבָאוֹת מַלְיָא כָל אַרְעָא זִיו יְקָרֵהּ. וַתִּשָּׂאֵנִי רוּחַ, וָאֶשְׁמַע אַחֲרַי קוֹל רַעַשׁ גָּדוֹל: בָּרוּךְ כְּבוֹד יהוה מִמְּקוֹמוֹ: וּנְטָלַתְנִי רוּחָא, וּשְׁמָעִית בַּתְרַי קַל זִיעַ שַׂגִּיא דִמְשַׁבְּחִין וְאָמְרִין: בְּרִיךְ יְקָרָא דַיהוה מֵאֲתָר בֵּית שְׁכִינְתֵּהּ. יהוה יִמְלֹךְ לְעוֹלָם וָעֶד: יהוה מַלְכוּתֵיהּ קָאֵים לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיהוה אֱלֹהֵי אַבְרָהָם יִצְחָק וְיִשְׂרָאֵל אֲבוֹתֵינוּ, שָׁמְרָה זֹּאת לְעוֹלָם, לְיֵצֶר מַחְשְׁבוֹת לְבַב עַמֶּךָ, וְהָכֵן לְבָבָם אֵלֶיךָ: וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית, וְהִרְבָּה לְהָשִׁיב אַפּוֹ, וְלֹא יָעִיר כָּל חֲמָתוֹ: כִּי אַתָּה יהוה טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ: צִדְקָתְךָ צֶּדֶק לְעוֹלָם, וְתוֹרָתְךָ אֱמֶת: תִּתֵּן אֱמֶת לְיַעֲקֹב, חֶסֶד לְאַבְרָהָם, אֲשֶׁר נִשְׁבַּעְתָּ לַאֲבֹתֵינוּ מִימֵי קֶדֶם: בָּרוּךְ אֲדֹנָי יוֹם יוֹם, יַעֲמָס לָנוּ הָאֵל יְשׁוּעָתֵנוּ, סֶלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב, סֶלָה: יהוה צְבָאוֹת אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":["em_kadosh"]},{"kind":"instruction","text":"יכוין למסור נפשו על קדושת שמו יתברך כשאומר זה:","cond":["em_kadosh"]},{"kind":"text","text":"בָּרוּךְ אֱלֹהֵינוּ שֶׁבְּרָאָנוּ לִכְבוֹדוֹ, וְהִבְדִּילָנוּ מִן הַתּוֹעִים, וְנָתַן לָנוּ תּוֹרַת אֱמֶת, וְחַיֵּי עוֹלָם נָטַע בְּתוֹכֵנוּ. הוּא יִפְתַּח לִבֵּנוּ בְּתוֹרָתוֹ, וְיָשִׂים בְּלִבֵּנוּ אַהֲבָתוֹ וְיִרְאָתוֹ לַעֲשׂוֹת רְצוֹנוֹ וּלְעָבְדוֹ בְּלֵבָב שָׁלֵם. לְמַעַן לֹא נִיגַע לָרִיק, וְלֹא נֵלֵד לַבֶּהָלָה. יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁנִּשְׁמֹר חֻקֶּיךָ וּמִצְוׂתֶיךָ בָּעוֹלָם הַזֶּה, וְנִזְכֶּה וְנִחְיֶה וְנִירַשׁ טוֹבָה וּבְרָכָה לְחַיֵּי הָעוֹלָם הַבָּא. לְמַעַן יְזַמֶּרְךָ כָבוֹד וְלֹא יִדֹּם, יהוה אֱלֹהַי לְעוֹלָם אוֹדֶךָּ: יהוה חָפֵץ לְמַעַן צִדְקוֹ, יַגְדִּיל תּורָה וְיַאְדִּיר: וְיִבְטְחוּ בְךָ יוֹדְעֵי שְׁמֶךָ, כִּי לֹא עָזַבְתָּ דֹּרְשֶׁיךָ יהוה: יהוה אֲדֹנֵינוּ, מָה אַדִּיר שִׁמְךָ בְּכָל הָאָרֶץ: חִזְקוּ וְיַאֲמֵץ לְבַבְכֶם כָּל הַמְיַחֲלִים לַיהוה:","cond":["em_kadosh"]},{"kind":"instruction","text":"קדיש תתקבל","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.\nתִּתְקַבַּל צְלוֹתָנָא וּבָעוּתָנָא עִם צְלוֹתְהוֹן וּבָעוּתְהוֹן דְּכָל בֵּית יִשְׂרָאֵל קֳדָם אֲבוּנָא דְבִשְׁמַיָּא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא, חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה וְשֵיזָבָא וּרְפוּאָה וּגְאֻלָּה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה, לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"header","text":"המשך תפילת יום העצמאות","cond":["yerushalayim"]},{"kind":"instruction","text":"פותחים את הארון\n\nהש\"ץ אומר והקהל עונה אחריו:","cond":["yerushalayim"]},{"kind":"text","text":"שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:\n\nיהוה הוּא הָאֱלֹהִים: יהוה הוּא הָאֱלֹהִים: יהוה הוּא הָאֱלֹהִים:","cond":["yerushalayim"]},{"kind":"instruction","text":"הש\"ץ אומר והקהל חוזר אחריו:","cond":["yerushalayim"]},{"kind":"text","text":"מִי שֶׁעָשָׂה נִסִּים לַאֲבוֹתֵינוּ וְלָנוּ וּגְאָלָנוּ מֵעַבְדּוּת לְחֵרוּת, הוּא יִגְאָלֵנוּ גְאֻלָּה שְׁלֵמָה בְּקָרוֹב, וִיקַבֵּץ נִדָּחֵינוּ מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ, חֲבֵרִים כָּל יִשְׂרָאֵל, וְנֹאמַר אָמֵן.","cond":["yerushalayim"]},{"kind":"instruction","text":"הש\"ץ אומר:","cond":["yerushalayim"]},{"kind":"text","text":"וְכִי-תָבֹאוּ מִלְחָמָה בְּאַרְצְכֶם, עַל-הַצַּר הַצֹּרֵר אֶתְכֶם, וַהֲרֵעֹתֶם בַּחֲצֹצְרֹת, וְנִזְכַּרְתֶּם לִפְנֵי יהוה אֱלֹהֵיכֶם וְנוֹשַׁעְתֶּם מֵאֹיְבֵיכֶם: וּבְיוֹם שִׂמְחַתְכֶם וּבְמוֹעֲדֵיכֶם וּבְרָאשֵׁי חָדְשֵׁיכֶם וּתְקַעְתֶּם בַּחֲצֹצְרֹת עַל עֹלֹתֵיכֶם וְעַל זִבְחֵי שַׁלְמֵיכֶם וְהָיוּ לָכֶם לְזִכָּרוֹן לִפְנֵי אֱלֹהֵיכֶם, אֲנִי יהוה אֱלֹהֵיכֶם:","cond":["yerushalayim"]},{"kind":"instruction","text":"תוקעים תקיעה גדולה ואומרים בקול רם:","cond":["yerushalayim"]},{"kind":"text","text":"לַשָּׁנָה הַבָּאָה בִּירוּשָׁלַיִם הַבְּנוּיָה.","cond":["yerushalayim"]},{"kind":"instruction","text":"(כל הקהל אומר","cond":["yerushalayim"]},{"kind":"text","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁכְּשֵׁם שֶׁזָּכִינוּ לְאַתְחַלְתָּא דִגְאֻלָּה, כֵּן נִזְכֶּה לִשְׁמֹעַ קוֹל שׁוֹפָרוֹ שֶׁל מָשִׁיחַ בִּמְהֵרָה בְיָמֵינוּ.)","cond":["yerushalayim"]},{"kind":"instruction","text":"ושרים במנגינת התקוה:","cond":["yerushalayim"]},{"kind":"text","text":"שִׁיר הַמַּעֲלוֹת בְּשׁוּב יהוה אֶת שִׁיבַת צִיּוֹן, הָיִינוּ כְּחֹלְמִים: אָז יִמָּלֵא שְׂחוֹק פִּינוּ וּלְשׁוֹנֵנוּ רִנָּה, אָז יֹאמְרוּ בַגּוֹיִם הִגְדִּיל יהוה לַעֲשׂוֹת עִם אֵלֶּה: הִגְדִּיל יהוה לַעֲשׂוֹת עִמָּנוּ, הָיִינוּ שְׂמֵחִים: שׁוּבָה יהוה אֶת שְׁבִיתֵנוּ כַּאֲפִיקִים בַּנֶּגֶב: הַזֹּרְעִים בְּדִמְעָה בְּרִנָּה יִקְצֹרוּ: הָלוֹךְ יֵלֵךְ וּבָכֹה נֹשֵׂא מֶשֶׁךְ הַזָּרַע, בֹּא יָבוֹא בְרִנָּה נֹשֵׂא אֲלֻמֹּתָיו:","cond":["yerushalayim"]},{"kind":"instruction","text":"מברך לאור הנר:","cond":["tishaaBeav","sun"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא מְאוֹרֵי הָאֵשׁ.","cond":["tishaaBeav","sun"]},{"kind":"header","text":"מגילת איכה","cond":["tishaaBeav"]},{"kind":"instruction","text":"מגילת איכה\n\n\nפרק א'","cond":["tishaaBeav"]},{"kind":"text","text":"אֵיכָה יָשְׁבָה בָדָד הָעִיר רַבָּתִי עָם הָיְתָה כְּאַלְמָנָה, רַבָּתִי בַגּוֹיִם, שָׂרָתִי בַּמְּדִינוֹת, הָיְתָה לָמַס: בָּכוֹ תִבְכֶּה בַּלַּיְלָה וְדִמְעָתָהּ עַל לֶחֱיָהּ, אֵין לָהּ מְנַחֵם מִכָּל אֹהֲבֶיהָ, כָּל רֵעֶיהָ בָּגְדוּ בָהּ, הָיוּ לָהּ לְאֹיְבִים: גָּלְתָה יְהוּדָה מֵעֹנִי וּמֵרֹב עֲבֹדָה, הִיא יָשְׁבָה בַגּוֹיִם, לֹא מָצְאָה מָנוֹחַ, כָּל רֹדְפֶיהָ הִשִּׂיגוּהָ בֵּין הַמְּצָרִים: דַּרְכֵי צִיּוֹן אֲבֵלוֹת מִבְּלִי בָּאֵי מוֹעֵד, כָּל שְׁעָרֶיהָ שׁוֹמֵמִין, כֹּהֲנֶיהָ נֶאֱנָחִים, בְּתוּלֹתֶיהָ נּוּגוֹת וְהִיא מַר לָהּ: הָיוּ צָרֶיהָ לְרֹאשׁ אֹיְבֶיהָ שָׁלוּ, כִּי יהוה הוֹגָהּ עַל רֹב פְּשָׁעֶיהָ, עוֹלָלֶיהָ הָלְכוּ שְׁבִי לִפְנֵי צָר: וַיֵּצֵא מִבַּת צִיּוֹן כָּל הֲדָרָהּ, הָיוּ שָׂרֶיהָ כְּאַיָּלִים לֹא מָצְאוּ מִרְעֶה, וַיֵּלְכוּ בְלֹא כֹחַ לִפְנֵי רוֹדֵף: זָכְרָה יְרוּשָׁלַיִם יְמֵי עָנְיָהּ וּמְרוּדֶיהָ, כֹּל מַחֲמֻדֶיהָ אֲשֶׁר הָיוּ מִימֵי קֶדֶם, בִּנְפֹל עַמָּהּ בְּיַד צָר וְאֵין עוֹזֵר לָהּ, רָאוּהָ צָרִים, שָׂחֲקוּ עַל מִשְׁבַּתֶּהָ: חֵטְא חָטְאָה יְרוּשָׁלַיִם, עַל כֵּן לְנִידָה הָיָתָה, כָּל מְכַבְּדֶיהָ הִזִּילוּהָ כִּי רָאוּ עֶרְוָתָהּ, גַּם הִיא נֶאֶנְחָה וַתָּשָׁב אָחוֹר: טֻמְאָתָהּ בְּשׁוּלֶיהָ, לֹא זָכְרָה אַחֲרִיתָהּ, וַתֵּרֶד פְּלָאִים, אֵין מְנַחֵם לָהּ, רְאֵה יהוה אֶת עָנְיִי כִּי הִגְדִּיל אוֹיֵב: יָדוֹ פָּרַשׂ צָר עַל כָּל מַחֲמַדֶּיהָ, כִּי רָאֲתָה גוֹיִם בָּאוּ מִקְדָּשָׁהּ, אֲשֶׁר צִוִּיתָה לֹא יָבֹאוּ בַקָּהָל לָךְ: כָּל עַמָּהּ נֶאֱנָחִים מְבַקְשִׁים לֶחֶם, נָתְנוּ מַחֲמַדֵּיהֶם בְּאֹכֶל לְהָשִׁיב נָפֶשׁ, רְאֵה יהוה וְהַבִּיטָה כִּי הָיִיתִי זוֹלֵלָה: לוֹא אֲלֵיכֶם כָּל עֹבְרֵי דֶרֶךְ, הַבִּיטוּ וּרְאוּ אִם יֵשׁ מַכְאוֹב כְּמַכְאֹבִי אֲשֶׁר עוֹלַל לִי, אֲשֶׁר הוֹגָה יהוה בְּיוֹם חֲרוֹן אַפּוֹ: מִמָּרוֹם שָׁלַח אֵשׁ בְּעַצְמֹתַי וַיִּרְדֶּנָּה, פָּרַשׂ רֶשֶׁת לְרַגְלַי הֱשִׁיבַנִי אָחוֹר, נְתָנַנִי שֹׁמֵמָה כָּל הַיּוֹם דָּוָה: נִשְׂקַד עֹל פְּשָׁעַי בְּיָדוֹ, יִשְׂתָּרְגוּ, עָלוּ עַל צַוָּארִי הִכְשִׁיל כֹּחִי, נְתָנַנִי אֲדֹנָי בִּידֵי לֹא אוּכַל קוּם: סִלָּה כָל אַבִּירַי אֲדֹנָי בְּקִרְבִּי, קָרָא עָלַי מוֹעֵד לִשְׁבֹּר בַּחוּרָי, גַּת דָּרַךְ אֲדֹנָי לִבְתוּלַת בַּת יְהוּדָה: עַל אֵלֶּה אֲנִי בוֹכִיָּה, עֵינִי עֵינִי יֹרְדָה מַּיִם, כִּי רָחַק מִמֶּנִּי מְנַחֵם מֵשִׁיב נַפְשִׁי, הָיוּ בָנַי שׁוֹמֵמִים כִּי גָבַר אוֹיֵב: פֵּרְשָׂה צִיּוֹן בְּיָדֶיהָ, אֵין מְנַחֵם לָהּ, צִוָּה יהוה לְיַעֲקֹב סְבִיבָיו צָרָיו, הָיְתָה יְרוּשָׁלַיִם לְנִדָּה בֵּינֵיהֶם: צַדִּיק הוּא יהוה כִּי פִיהוּ מָרִיתִי, שִׁמְעוּ נָא כָל הָעַמִּים וּרְאוּ מַכְאֹבִי, בְּתוּלֹתַי וּבַחוּרַי הָלְכוּ בַשֶּׁבִי: קָרָאתִי לַמְאַהֲבַי הֵמָּה רִמּוּנִי, כֹּהֲנַי וּזְקֵנַי בָּעִיר גָּוָעוּ, כִּי בִקְשׁוּ אֹכֶל לָמוֹ וְיָשִׁיבוּ אֶת נַפְשָׁם: רְאֵה יהוה כִּי צַר לִי מֵעַי חֳמַרְמָרוּ, נֶהְפַּךְ לִבִּי בְּקִרְבִּי כִּי מָרוֹ מָרִיתִי, מִחוּץ שִׁכְּלָה חֶרֶב, בַּבַּיִת כַּמָּוֶת: שָׁמְעוּ כִּי נֶאֱנָחָה אָנִי, אֵין מְנַחֵם לִי, כָּל אֹיְבַי שָׁמְעוּ רָעָתִי שָׂשׂוּ כִּי אַתָּה עָשִׂיתָ, הֵבֵאתָ יוֹם קָרָאתָ וְיִהְיוּ כָמוֹנִי: תָּבֹא כָל רָעָתָם לְפָנֶיךָ וְעוֹלֵל לָמוֹ, כַּאֲשֶׁר עוֹלַלְתָּ לִי עַל כָּל פְּשָׁעָי, כִּי רַבּוֹת אַנְחֹתַי וְלִבִּי דַוָּי:","cond":["tishaaBeav"]},{"kind":"instruction","text":"פרק ב'","cond":["tishaaBeav"]},{"kind":"text","text":"אֵיכָה יָעִיב בְּאַפּוֹ אֲדֹנָי אֶת בַּת צִיּוֹן, הִשְׁלִיךְ מִשָּׁמַיִם אֶרֶץ, תִּפְאֶרֶת יִשְׂרָאֵל, וְלֹא זָכַר הֲדֹם רַגְלָיו בְּיוֹם אַפּוֹ: בִּלַּע אֲדֹנָי וְלֹא חָמַל אֵת כָּל נְאוֹת יַעֲקֹב, הָרַס בְּעֶבְרָתוֹ מִבְצְרֵי בַת יְהוּדָה הִגִּיעַ לָאָרֶץ, חִלֵּל מַמְלָכָה וְשָׂרֶיהָ: גָּדַע בָּחֳרִי אַף כֹּל קֶרֶן יִשְׂרָאֵל, הֵשִׁיב אָחוֹר יְמִינוֹ מִפְּנֵי אוֹיֵב, וַיִּבְעַר בְּיַעֲקֹב כְּאֵשׁ לֶהָבָה, אָכְלָה סָבִיב: דָּרַךְ קַשְׁתּוֹ כְּאוֹיֵב, נִצָּב יְמִינוֹ כְּצָר, וַיַּהֲרֹג כֹּל מַחֲמַדֵּי עָיִן, בְּאֹהֶל בַּת צִיּוֹן שָׁפַךְ כָּאֵשׁ חֲמָתוֹ: הָיָה אֲדֹנָי כְּאוֹיֵב, בִּלַּע יִשְׂרָאֵל, בִּלַּע כָּל אַרְמְנוֹתֶיהָ שִׁחֵת מִבְצָרָיו, וַיֶּרֶב בְּבַת יְהוּדָה תַּאֲנִיָּה וַאֲנִיָּה: וַיַּחְמֹס כַּגַּן שֻׂכּוֹ שִׁחֵת מוֹעֲדוֹ, שִׁכַּח יהוה בְּצִיּוֹן מוֹעֵד וְשַׁבָּת, וַיִּנְאַץ בְּזַעַם אַפּוֹ מֶלֶךְ וְכֹהֵן: זָנַח אֲדֹנָי מִזְבְּחוֹ, נִאֵר מִקְדָּשׁוֹ, הִסְגִּיר בְּיַד אוֹיֵב חוֹמֹת אַרְמְנוֹתֶיהָ, קוֹל נָתְנוּ בְּבֵית יהוה כְּיוֹם מוֹעֵד: חָשַׁב יהוה לְהַשְׁחִית חוֹמַת בַּת צִיּוֹן, נָטָה קָו לֹא הֵשִׁיב יָדוֹ מִבַּלֵּעַ, וַיַּאֲבֶל חֵל וְחוֹמָה יַחְדָּו אֻמְלָלוּ: טָבְעוּ בָאָרֶץ שְׁעָרֶיהָ, אִבַּד וְשִׁבַּר בְּרִיחֶיהָ, מַלְכָּהּ וְשָׂרֶיהָ בַגּוֹיִם אֵין תּוֹרָה, גַּם נְבִיאֶיהָ לֹא מָצְאוּ חָזוֹן מֵיהוה: יֵשְׁבוּ לָאָרֶץ יִדְּמוּ זִקְנֵי בַת צִיּוֹן, הֶעֱלוּ עָפָר עַל רֹאשָׁם, חָגְרוּ שַׂקִּים, הוֹרִידוּ לָאָרֶץ רֹאשָׁן בְּתוּלֹת יְרוּשָׁלַיִם: כָּלוּ בַדְּמָעוֹת עֵינַי חֳמַרְמְרוּ מֵעַי, נִשְׁפַּךְ לָאָרֶץ כְּבֵדִי עַל שֶׁבֶר בַּת עַמִּי, בֵּעָטֵף עוֹלֵל וְיוֹנֵק בִּרְחֹבוֹת קִרְיָה: לְאִמֹּתָם יֹאמְרוּ אַיֵּה דָּגָן וָיָיִן, בְּהִתְעַטְּפָם כֶּחָלָל בִּרְחֹבוֹת עִיר, בְּהִשְׁתַּפֵּךְ נַפְשָׁם אֶל חֵיק אִמֹּתָם: מָה אֲעִידֵךְ מָה אֲדַמֶּה לָּךְ, הַבַּת יְרוּשָׁלַיִם, מָה אַשְׁוֶה לָּךְ וַאֲנַחֲמֵךְ בְּתוּלַת בַּת צִיּוֹן, כִּי גָדוֹל כַּיָּם שִׁבְרֵךְ מִי יִרְפָּא לָךְ: נְבִיאַיִךְ חָזוּ לָךְ שָׁוְא וְתָפֵל, וְלֹא גִלּוּ עַל עֲוׂנֵךְ לְהָשִׁיב שְׁבוּתֵךְ, וַיֶּחֱזוּ לָךְ מַשְׂאוֹת שָׁוְא וּמַדּוּחִים: סָפְקוּ עָלַיִךְ כַּפַּיִם כָּל עֹבְרֵי דֶרֶךְ, שָׁרְקוּ וַיָּנִעוּ רֹאשָׁם עַל בַּת יְרוּשָׁלָיִם, הֲזֹאת הָעִיר שֶׁיֹּאמְרוּ כְּלִילַת יֹפִי, מָשׂוֹשׂ לְכָל הָאָרֶץ: פָּצוּ עָלַיִךְ פִּיהֶם כָּל אוֹיְבַיִךְ, שָׁרְקוּ וַיַּחַרְקוּ שֵׁן, אָמְרוּ בִּלָּעְנוּ, אַךְ זֶה הַיּוֹם שֶׁקִּוִּינֻהוּ מָצָאנוּ רָאִינוּ: עָשָׂה יהוה אֲשֶׁר זָמָם, בִּצַּע אֶמְרָתוֹ אֲשֶׁר צִוָּה מִימֵי קֶדֶם, הָרַס וְלֹא חָמָל, וַיְשַׂמַּח עָלַיִךְ אוֹיֵב, הֵרִים קֶרֶן צָרָיִךְ: צָעַק לִבָּם אֶל אֲדֹנָי, חוֹמַת בַּת צִיּוֹן הוֹרִידִי כַנַּחַל דִּמְעָה יוֹמָם וָלַיְלָה, אַל תִּתְּנִי פוּגַת לָךְ, אַל תִּדֹּם בַּת עֵינֵךְ: קוּמִי רֹנִּי בַלַּיְלָה לְרֹאשׁ אַשְׁמֻרוֹת, שִׁפְכִי כַמַּיִם לִבֵּךְ נֹכַח פְּנֵי אֲדֹנָי, שְׂאִי אֵלָיו כַּפַּיִךְ עַל נֶפֶשׁ עוֹלָלַיִךְ הָעֲטוּפִים בְּרָעָב בְּרֹאשׁ כָּל חוּצוֹת: רְאֵה יהוה וְהַבִּיטָה לְמִי עוֹלַלְתָּ כֹּה, אִם תֹּאכַלְנָה נָשִׁים פִּרְיָם עֹלְלֵי טִפֻּחִים, אִם יֵהָרֵג בְּמִקְדַּשׁ אֲדֹנָי כֹּהֵן וְנָבִיא: שָׁכְבוּ לָאָרֶץ חוּצוֹת נַעַר וְזָקֵן, בְּתוּלֹתַי וּבַחוּרַי נָפְלוּ בֶחָרֶב, הָרַגְתָּ בְּיוֹם אַפֶּךָ, טָבַחְתָּ לֹא חָמָלְתָּ: תִּקְרָא כְיוֹם מוֹעֵד מְגוּרַי מִסָּבִיב וְלֹא הָיָה בְּיוֹם אַף יהוה פָּלִיט וְשָׂרִיד, אֲשֶׁר טִפַּחְתִּי וְרִבִּיתִי אֹיְבִי כִלָּם:","cond":["tishaaBeav"]},{"kind":"instruction","text":"פרק ג'","cond":["tishaaBeav"]},{"kind":"text","text":"אֲנִי הַגֶּבֶר רָאָה עֳנִי בְּשֵׁבֶט עֶבְרָתוֹ: אוֹתִי נָהַג וַיֹּלַךְ חֹשֶׁךְ וְלֹא אוֹר: אַךְ בִּי יָשֻׁב יַהֲפֹךְ יָדוֹ כָּל הַיּוֹם: בִּלָּה בְשָׂרִי וְעוֹרִי, שִׁבַּר עַצְמוֹתָי: בָּנָה עָלַי, וַיַּקַּף רֹאשׁ וּתְלָאָה: בְּמַחֲשַׁכִּים הוֹשִׁיבַנִי כְּמֵתֵי עוֹלָם: גָּדַר בַּעֲדִי וְלֹא אֵצֵא, הִכְבִּיד נְחָשְׁתִּי: גַּם כִּי אֶזְעַק וַאֲשַׁוֵּעַ שָׂתַם תְּפִלָּתִי: גָּדַר דְּרָכַי בְּגָזִית, נְתִיבֹתַי עִוָּה: דֹּב אֹרֵב הוּא לִי, אֲרִי בְּמִסְתָּרִים: דְּרָכַי סוֹרֵר וַיְפַשְּׁחֵנִי, שָׂמַנִי שֹׁמֵם: דָּרַךְ קַשְׁתּוֹ וַיַּצִּיבֵנִי כַּמַּטָּרָא לַחֵץ: הֵבִיא בְּכִלְיוֹתָי בְּנֵי אַשְׁפָּתוֹ: הָיִיתִי שְּׂחֹק לְכָל עַמִּי, נְגִינָתָם כָּל הַיּוֹם: הִשְׂבִּיעַנִי בַמְּרוֹרִים הִרְוַנִי לַעֲנָה: וַיַּגְרֵס בֶּחָצָץ שִׁנָּי, הִכְפִּישַׁנִי בָּאֵפֶר: וַתִּזְנַח מִשָּׁלוֹם נַפְשִׁי, נָשִׁיתִי טוֹבָה: וָאֹמַר אָבַד נִצְחִי וְתוֹחַלְתִּי מֵיהוה: זְכָר עָנְיִי וּמְרוּדִי, לַעֲנָה וָרֹאשׁ: זָכוֹר תִּזְכּוֹר וְתָשׁוֹחַ עָלַי נַפְשִׁי: זֹאת אָשִׁיב אֶל לִבִּי, עַל כֵּן אוֹחִיל: חַסְדֵי יהוה כִּי לֹא תָמְנוּ, כִּי לֹא כָלוּ רַחֲמָיו: חֲדָשִׁים לַבְּקָרִים רַבָּה אֱמוּנָתֶךָ: חֶלְקִי יהוה אָמְרָה נַפְשִׁי, עַל כֵּן אוֹחִיל לוֹ: טוֹב יהוה לְקֹוָו, לְנֶפֶשׁ תִּדְרְשֶׁנּוּ: טוֹב וְיָחִיל וְדוּמָם לִתְשׁוּעַת יהוה: טוֹב לַגֶּבֶר כִּי יִשָּׂא עֹל בִּנְעוּרָיו: יֵשֵׁב בָּדָד וְיִדֹּם כִּי נָטַל עָלָיו: יִתֵּן בֶּעָפָר פִּיהוּ, אוּלַי יֵשׁ תִּקְוָה: יִתֵּן לְמַכֵּהוּ לֶחִי, יִשְׂבַּע בְּחֶרְפָּה: כִּי לֹא יִזְנַח לְעוֹלָם אֲדֹנָי: כִּי אִם הוֹגָה וְרִחַם כְּרֹב חֲסָדָיו: כִּי לֹא עִנָּה מִלִּבּוֹ, וַיַּגֶּה בְּנֵי אִישׁ: לְדַכֵּא תַּחַת רַגְלָיו כֹּל אֲסִירֵי אָרֶץ: לְהַטּוֹת מִשְׁפַּט גָּבֶר נֶגֶד פְּנֵי עֶלְיוֹן: לְעַוֵּת אָדָם בְּרִיבוֹ אֲדֹנָי לֹא רָאָה: מִי זֶה אָמַר וַתֶּהִי, אֲדֹנָי לֹא צִוָּה: מִפִּי עֶלְיוֹן לֹא תֵצֵא הָרָעוֹת וְהַטּוֹב: מַה יִּתְאוֹנֵן אָדָם חָי, גֶּבֶר עַל חֲטָאָיו: נַחְפְּשָׂה דְרָכֵינוּ וְנַחְקֹרָה, וְנָשׁוּבָה עַד יהוה: נִשָּׂא לְבָבֵנוּ אֶל כַּפָּיִם, אֶל אֵל בַּשָּׁמָיִם: נַחְנוּ פָשַׁעְנוּ וּמָרִינוּ, אַתָּה לֹא סָלָחְתָּ: סַכֹּתָה בָאַף וַתִּרְדְּפֵנוּ, הָרַגְתָּ לֹא חָמָלְתָּ: סַכּוֹתָה בֶעָנָן לָךְ מֵעֲבוֹר תְּפִלָּה: סְחִי וּמָאוֹס תְּשִׂימֵנוּ בְּקֶרֶב הָעַמִּים: פָּצוּ עָלֵינוּ פִּיהֶם כָּל אֹיְבֵינוּ: פַּחַד וָפַחַת הָיָה לָנוּ, הַשֵּׁאת וְהַשָּׁבֶר: פַּלְגֵי מַיִם תֵּרַד עֵינִי עַל שֶׁבֶר בַּת עַמִּי: עֵינִי נִגְּרָה וְלֹא תִדְמֶה מֵאֵין הֲפֻגוֹת: עַד יַשְׁקִיף וְיֵרֶא יהוה מִשָּׁמָיִם: עֵינִי עוֹלְלָה לְנַפְשִׁי מִכֹּל בְּנוֹת עִירִי: צוֹד צָדוּנִי כַּצִּפּוֹר אֹיְבַי חִנָּם: צָמְתוּ בַבּוֹר חַיָּי וַיַּדּוּ אֶבֶן בִּי: צָפוּ מַיִם עַל רֹאשִׁי, אָמַרְתִּי נִגְזָרְתִּי: קָרָאתִי שִׁמְךָ יהוה מִבּוֹר תַּחְתִּיּוֹת: קוֹלִי שָׁמָעְתָּ, אַל תַּעְלֵם אָזְנְךָ לְרַוְחָתִי לְשַׁוְעָתִי: קָרַבְתָּ בְּיוֹם אֶקְרָאֶךָּ, אָמַרְתָּ אַל תִּירָא: רַבְתָּ אֲדֹנָי רִיבֵי נַפְשִׁי, גָּאַלְתָּ חַיָּי: רָאִיתָה יהוה עַוָּתָתִי, שָׁפְטָה מִשְׁפָּטִי: רָאִיתָה כָּל נִקְמָתָם, כָּל מַחְשְׁבֹתָם לִי: שָׁמַעְתָּ חֶרְפָּתָם יהוה, כָּל מַחְשְׁבֹתָם עָלָי: שִׂפְתֵי קָמַי וְהֶגְיוֹנָם עָלַי כָּל הַיּוֹם: שִׁבְתָּם וְקִימָתָם הַבִּיטָה, אֲנִי מַנְגִּינָתָם: תָּשִׁיב לָהֶם גְּמוּל, יהוה, כְּמַעֲשֵׂה יְדֵיהֶם: תִּתֵּן לָהֶם מְגִנַּת לֵב, תַּאֲלָתְךָ לָהֶם: תִּרְדֹּף בְּאַף וְתַשְׁמִידֵם מִתַּחַת שְׁמֵי יהוה:","cond":["tishaaBeav"]},{"kind":"instruction","text":"פרק ד'","cond":["tishaaBeav"]},{"kind":"text","text":"אֵיכָה יוּעַם זָהָב יִשְׁנֶא הַכֶּתֶם הַטּוֹב, תִּשְׁתַּפֵּכְנָה אַבְנֵי קֹדֶשׁ בְּרֹאשׁ כָּל חוּצוֹת: בְּנֵי צִיּוֹן הַיְקָרִים הַמְסֻלָּאִים בַּפָּז, אֵיכָה נֶחְשְׁבוּ לְנִבְלֵי חֶרֶשׂ מַעֲשֵׂה יְדֵי יוֹצֵר: גַּם תַּנִּים חָלְצוּ שַׁד, הֵינִיקוּ גּוּרֵיהֶן, בַּת עַמִּי לְאַכְזָר כַּיְעֵנִים בַּמִּדְבָּר: דָּבַק לְשׁוֹן יוֹנֵק אֶל חִכּוֹ בַּצָּמָא, עוֹלָלִים שָׁאֲלוּ לֶחֶם, פֹּרֵשׂ אֵין לָהֶם: הָאֹכְלִים לְמַעֲדַנִּים נָשַׁמּוּ בַּחוּצוֹת, הָאֱמֻנִים עֲלֵי תוֹלָע חִבְּקוּ אַשְׁפַּתּוֹת: וַיִּגְדַּל עֲוׂן בַּת עַמִּי מֵחַטַּאת סְדֹם הַהֲפוּכָה כְמוֹ רָגַע, וְלֹא חָלוּ בָהּ יָדָיִם: זַכּוּ נְזִירֶיהָ מִשֶּׁלֶג, צַחוּ מֵחָלָב, אָדְמוּ עֶצֶם מִפְּנִינִים, סַפִּיר גִּזְרָתָם: חָשַׁךְ מִשְּׁחוֹר תָּאֳרָם, לֹא נִכְּרוּ בַּחוּצוֹת, צָפַד עוֹרָם עַל עַצְמָם, יָבֵשׁ הָיָה כָעֵץ: טוֹבִים הָיוּ חַלְלֵי חֶרֶב מֵחַלְלֵי רָעָב, שֶׁהֵם יָזוּבוּ מְדֻקָּרִים מִתְּנוּבֹת שָׂדָי: יְדֵי נָשִׁים רַחֲמָנִיּוֹת בִּשְּׁלוּ יַלְדֵיהֶן, הָיוּ לְבָרוֹת לָמוֹ בְּשֶׁבֶר בַּת עַמִּי: כִּלָּה יהוה אֶת חֲמָתוֹ, שָׁפַךְ חֲרוֹן אַפּוֹ, וַיַּצֶּת אֵשׁ בְּצִיּוֹן וַתֹּאכַל יְסוֹדֹתֶיהָ: לֹא הֶאֱמִינוּ מַלְכֵי אֶרֶץ כֹּל יֹשְׁבֵי תֵבֵל, כִּי יָבֹא צַר וְאוֹיֵב בְּשַׁעֲרֵי יְרוּשָׁלָיִם: מֵחַטֹּאת נְבִיאֶיהָ, עֲוׂנוֹת כֹּהֲנֶיהָ, הַשֹּׁפְכִים בְּקִרְבָּהּ דַּם צַדִּיקִים: נָעוּ עִוְרִים בַּחוּצוֹת נְגֹאֲלוּ בַּדָּם, בְּלֹא יוּכְלוּ יִגְּעוּ בִּלְבֻשֵׁיהֶם: סוּרוּ טָמֵא, קָרְאוּ לָמוֹ, סוּרוּ סוּרוּ אַל תִּגָּעוּ, כִּי נָצוּ גַּם נָעוּ, אָמְרוּ בַּגּוֹיִם לֹא יוֹסִיפוּ לָגוּר: פְּנֵי יהוה חִלְּקָם לֹא יוֹסִיף לְהַבִּיטָם, פְּנֵי כֹהֲנִים לֹא נָשָׂאוּ וּזְקֵנִים לֹא חָנָנוּ: עוֹדֵינוּ תִּכְלֶינָה עֵינֵינוּ אֶל עֶזְרָתֵנוּ הָבֶל, בְּצִפִּיָּתֵנוּ צִפִּינוּ אֶל גּוֹי לֹא יוֹשִׁעַ: צָדוּ צְעָדֵינוּ מִלֶּכֶת בִּרְחֹבֹתֵינוּ, קָרַב קִצֵּינוּ מָלְאוּ יָמֵינוּ כִּי בָא קִצֵּינוּ: קַלִּים הָיוּ רֹדְפֵינוּ מִנִּשְׁרֵי שָׁמָיִם, עַל הֶהָרִים דְּלָקֻנוּ, בַּמִּדְבָּר אָרְבוּ לָנוּ: רוּחַ אַפֵּינוּ מְשִׁיחַ יהוה נִלְכַּד בִּשְׁחִיתוֹתָם, אֲשֶׁר אָמַרְנוּ בְּצִלּוֹ נִחְיֶה בַגּוֹיִם: שִׂישִׂי וְשִׂמְחִי בַּת אֱדוֹם יוֹשֶׁבֶת בְּאֶרֶץ עוּץ, גַּם עָלַיִךְ תַּעֲבָר כּוֹס, תִּשְׁכְּרִי וְתִתְעָרִי: תַּם עֲוׂנֵךְ בַּת צִיּוֹן, לֹא יוֹסִיף לְהַגְלוֹתֵךְ, פָּקַד עֲוׂנֵךְ בַּת אֱדוֹם, גִּלָּה עַל חַטֹּאתָיִךְ:","cond":["tishaaBeav"]},{"kind":"instruction","text":"פרק ה'","cond":["tishaaBeav"]},{"kind":"text","text":"זְכֹר יהוה מֶה הָיָה לָנוּ, הַבִּיטָה וּרְאֵה אֶת חֶרְפָּתֵנוּ: נַחֲלָתֵנוּ נֶהֶפְכָה לְזָרִים, בָּתֵּינוּ לְנָכְרִים: יְתוֹמִים הָיִינוּ וְאֵין אָב, אִמֹּתֵינוּ כְּאַלְמָנוֹת: מֵימֵינוּ בְּכֶסֶף שָׁתִינוּ, עֵצֵינוּ בִּמְחִיר יָבֹאוּ: עַל צַוָּארֵנוּ נִרְדָּפְנוּ, יָגַעְנוּ וְלֹא הוּנַח לָנוּ: מִצְרַיִם נָתַנּוּ יָד, אַשּׁוּר לִשְׂבֹּעַ לָחֶם: אֲבֹתֵינוּ חָטְאוּ וְאֵינָם, וַאֲנַחְנוּ עֲוׂנֹתֵיהֶם סָבָלְנוּ: עֲבָדִים מָשְׁלוּ בָנוּ, פֹּרֵק אֵין מִיָּדָם: בְּנַפְשֵׁנוּ נָבִיא לַחְמֵנוּ מִפְּנֵי חֶרֶב הַמִּדְבָּר: עוֹרֵנוּ כְּתַנּוּר נִכְמָרוּ מִפְּנֵי זַלְעֲפוֹת רָעָב: נָשִׁים בְּצִיּוֹן עִנּוּ, בְּתֻלֹת בְּעָרֵי יְהוּדָה: שָׂרִים בְּיָדָם נִתְלוּ, פְּנֵי זְקֵנִים לֹא נֶהְדָּרוּ: בַּחוּרִים טְחוֹן נָשָׂאוּ, וּנְעָרִים בָּעֵץ כָּשָׁלוּ: זְקֵנִים מִשַּׁעַר שָׁבָתוּ, בַּחוּרִים מִנְּגִינָתָם: שָׁבַת מְשׂוֹשׂ לִבֵּנוּ, נֶהְפַּךְ לְאֵבֶל מְחֹלֵנוּ: נָפְלָה עֲטֶרֶת רֹאשֵׁנוּ, אוֹי נָא לָנוּ כִּי חָטָאנוּ: עַל זֶה הָיָה דָוֶה לִבֵּנוּ, עַל אֵלֶּה חָשְׁכוּ עֵינֵינוּ: עַל הַר צִיּוֹן שֶׁשָּׁמֵם, שׁוּעָלִים הִלְּכוּ בוֹ: אַתָּה יהוה לְעוֹלָם תֵּשֵׁב, כִּסְאֲךָ לְדֹר וָדוֹר: לָמָּה לָנֶצַח תִּשְׁכָּחֵנוּ, תַּעַזְבֵנוּ לְאֹרֶךְ יָמִים: הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם: כִּי אִם מָאֹס מְאַסְתָּנוּ, קָצַפְתָּ עָלֵינוּ עַד מְאֹד:","cond":["tishaaBeav"]},{"kind":"special","text":"הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם:","cond":["tishaaBeav"]},{"kind":"header","text":"מגילת אסתר","cond":["megilatEster"]},{"kind":"instruction","text":"הקורא את המגילה מברך לפניה. בברכת שהחיינו יכוון גם על שאר מצוות היום: מתנות לאביונים, משלוח מנות ומשתה ושמחה.","cond":["megilatEster"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ עַל מִקְרָא מְגִלָּה.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁעָשָׂה נִסִּים לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה.","cond":["megilatEster"]},{"kind":"text","text":"בָּרוּךְ אַָתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁהֶחֱיָנוּ וְקִיְּמָנוּ וְהִגִּיעָנוּ לַזְּמַן הַזֶּה.","cond":["megilatEster"]},{"kind":"header","text":"פרק א'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק א'","cond":["megilatEster"]},{"kind":"text","text":"וַיְהִי בִּימֵי אֲחַשְׁוֵרוֹשׁ, הוּא אֲחַשְׁוֵרוֹשׁ הַמֹּלֵךְ מֵהֹדּוּ וְעַד כּוּשׁ, שֶׁבַע וְעֶשְׂרִים וּמֵאָה מְדִינָה: בַּיָּמִים הָהֵם, כְּשֶׁבֶת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ עַל כִּסֵּא מַלְכוּתוֹ אֲשֶׁר בְּשׁוּשַׁן הַבִּירָה: בִּשְׁנַת שָׁלוֹשׁ לְמָלְכוֹ עָשָׂה מִשְׁתֶּה לְכָל שָׂרָיו וַעֲבָדָיו, חֵיל פָּרַס וּמָדַי הַפַּרְתְּמִים וְשָׂרֵי הַמְּדִינוֹת לְפָנָיו: בְּהַרְאֹתוֹ אֶת עֹשֶׁר כְּבוֹד מַלְכוּתוֹ וְאֶת יְקָר תִּפְאֶרֶת גְּדוּלָּתוֹ, יָמִים רַבִּים שְׁמוֹנִים וּמְאַת יוֹם: וּבִמְלוֹאת הַיָּמִים הָאֵלֶּה עָשָׂה הַמֶּלֶךְ לְכָל הָעָם הַנִּמְצְאִים בְּשׁוּשַׁן הַבִּירָה לְמִגָּדוֹל וְעַד קָטָן מִשְׁתֶּה שִׁבְעַת יָמִים, בַּחֲצַר גִּנַּת בִּיתַן הַמֶּלֶךְ: חוּר כַּרְפַּס וּתְכֵלֶת אָחוּז בְּחַבְלֵי בוּץ וְאַרְגָּמָן עַל גְּלִילֵי כֶסֶף וְעַמּוּדֵי שֵׁשׁ, מִטּוֹת זָהָב וָכֶסֶף עַל רִצְפַת בַּהַט וָשֵׁשׁ וְדַר וְסֹחָרֶת: וְהַשְׁקוֹת בִּכְלֵי זָהָב וְכֵלִים מִכֵּלִים שׁוֹנִים, וְיֵין מַלְכוּת רָב כְּיַד הַמֶּלֶךְ: וְהַשְּׁתִיָּה כַדָּת אֵין אֹנֵס, כִּי כֵן יִסַּד הַמֶּלֶךְ עַל כָּל רַב בֵּיתוֹ לַעֲשׂוֹת כִּרְצוֹן אִישׁ וָאִישׁ: גַּם וַשְׁתִּי הַמַּלְכָּה עָשְׂתָה מִשְׁתֵּה נָשִׁים, בֵּית הַמַּלְכוּת אֲשֶׁר לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: בַּיּוֹם הַשְּׁבִיעִי כְּטוֹב לֵב הַמֶּלֶךְ בַּיָּיִן, אָמַר לִמְהוּמָן בִּזְּתָא חַרְבוֹנָא בִּגְתָא וַאֲבַגְתָא זֵתַר וְכַרְכַּס שִׁבְעַת הַסָּרִיסִים הַמְשָׁרְתִים אֶת פְּנֵי הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: לְהָבִיא אֶת וַשְׁתִּי הַמַּלְכָּה לִפְנֵי הַמֶּלֶךְ בְּכֶתֶר מַלְכוּת, לְהַרְאוֹת הָעַמִּים וְהַשָּׂרִים אֶת יָפְיָהּ, כִּי טוֹבַת מַרְאֶה הִיא: וַתְּמָאֵן הַמַּלְכָּה וַשְׁתִּי לָבוֹא בִּדְבַר הַמֶּלֶךְ אֲשֶׁר בְּיַד הַסָּרִיסִים, וַיִּקְצֹף הַמֶּלֶךְ מְאֹד וַחֲמָתוֹ בָּעֲרָה בוֹ: וַיֹּאמֶר הַמֶּלֶךְ לַחֲכָמִים יֹדְעֵי הָעִתִּים, כִּי כֵן דְּבַר הַמֶּלֶךְ לִפְנֵי כָּל יֹדְעֵי דָּת וָדִין: וְהַקָּרֹב אֵלָיו כַּרְשְׁנָא שֵׁתָר אַדְמָתָא תַרְשִׁישׁ מֶרֶס מַרְסְנָא מְמוּכָן, שִׁבְעַת שָׂרֵי פָּרַס וּמָדַי רֹאֵי פְּנֵי הַמֶּלֶךְ הַיֹּשְׁבִים רִאשֹׁנָה בַּמַּלְכוּת: כְּדָת מַה לַּעֲשׂוֹת בַּמַּלְכָּה וַשְׁתִּי, עַל אֲשֶׁר לֹא עָשְׂתָה אֶת מַאֲמַר הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ בְּיַד הַסָּרִיסִים: וַיֹּאמֶר מְמוּכָן לִפְנֵי הַמֶּלֶךְ וְהַשָּׂרִים, לֹא עַל הַמֶּלֶךְ לְבַדּוֹ עָוְתָה וַשְׁתִּי הַמַּלְכָּה, כִּי עַל כָּל הַשָּׂרִים וְעַל כָּל הָעַמִּים אֲשֶׁר בְּכָל מְדִינוֹת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: כִּי יֵצֵא דְבַר הַמַּלְכָּה עַל כָּל הַנָּשִׁים לְהַבְזוֹת בַּעְלֵיהֶן בְּעֵינֵיהֶן, בְּאָמְרָם הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ אָמַר לְהָבִיא אֶת וַשְׁתִּי הַמַּלְכָּה לְפָנָיו וְלֹא בָאָה: וְהַיּוֹם הַזֶּה תֹּאמַרְנָה שָׂרוֹת פָּרַס וּמָדַי אֲשֶׁר שָׁמְעוּ אֶת דְּבַר הַמַּלְכָּה לְכֹל שָׂרֵי הַמֶּלֶךְ, וּכְדַי בִּזָּיוֹן וָקָצֶף: אִם עַל הַמֶּלֶךְ טוֹב יֵצֵא דְבַר מַלְכוּת מִלְּפָנָיו וְיִכָּתֵב בְּדָתֵי פָרַס וּמָדַי וְלֹא יַעֲבוֹר, אֲשֶׁר לֹא תָבוֹא וַשְׁתִּי לִפְנֵי הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ וּמַלְכוּתָהּ יִתֵּן הַמֶּלֶךְ לִרְעוּתָהּ הַטּוֹבָה מִמֶּנָּה: וְנִשְׁמַע פִּתְגָם הַמֶּלֶךְ אֲשֶׁר יַעֲשֶׂה בְּכָל מַלְכוּתוֹ כִּי רַבָּה הִיא, וְכָל הַנָּשִׁים יִתְּנוּ יְקָר לְבַעְלֵיהֶן לְמִגָּדוֹל וְעַד קָטָן: וַיִּיטַב הַדָּבָר בְּעֵינֵי הַמֶּלֶךְ וְהַשָּׂרִים, וַיַּעַשׂ הַמֶּלֶךְ כִּדְבַר מְמוּכָן: וַיִּשְׁלַח סְפָרִים אֶל כָּל מְדִינוֹת הַמֶּלֶךְ, אֶל מְדִינָה וּמְדִינָה כִּכְתָבָהּ וְאֶל עַם וָעָם כִּלְשׁוֹנוֹ, לִהְיוֹת כָּל אִישׁ שֹׂרֵר בְּבֵיתוֹ וּמְדַבֵּר כִּלְשׁוֹן עַמּוֹ:","cond":["megilatEster"]},{"kind":"header","text":"פרק ב'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ב'","cond":["megilatEster"]},{"kind":"text","text":"אַחַר הַדְּבָרִים הָאֵלֶּה כְּשֹׁךְ חֲמַת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, זָכַר אֶת וַשְׁתִּי וְאֵת אֲשֶׁר עָשָׂתָה וְאֵת אֲשֶׁר נִגְזַר עָלֶיהָ: וַיֹּאמְרוּ נַעֲרֵי הַמֶּלֶךְ מְשָׁרְתָיו, יְבַקְשׁוּ לַמֶּלֶךְ נְעָרוֹת בְּתוּלוֹת טוֹבוֹת מַרְאֶה: וְיַפְקֵד הַמֶּלֶךְ פְּקִידִים בְּכָל מְדִינוֹת מַלְכוּתוֹ, וְיִקְבְּצוּ אֶת כָּל נַעֲרָה בְתוּלָה טוֹבַת מַרְאֶה אֶל שׁוּשַׁן הַבִּירָה אֶל בֵּית הַנָּשִׁים אֶל יַד הֵגֶא סְרִיס הַמֶּלֶךְ שֹׁמֵר הַנָּשִׁים, וְנָתוֹן תַּמְרוּקֵיהֶן: וְהַנַּעֲרָה אֲשֶׁר תִּיטַב בְּעֵינֵי הַמֶּלֶךְ תִּמְלֹךְ תַּחַת וַשְׁתִּי, וַיִּיטַב הַדָּבָר בְּעֵינֵי הַמֶּלֶךְ וַיַּעַשׂ כֵּן:","cond":["megilatEster"]},{"kind":"special","text":"אִישׁ יְהוּדִי הָיָה בְּשׁוּשַׁן הַבִּירָה, וּשְׁמוֹ מָרְדֳּכַי בֶּן יָאִיר בֶּן שִׁמְעִי בֶּן קִישׁ אִישׁ יְמִינִי:","cond":["megilatEster"]},{"kind":"text","text":"אֲשֶׁר הָגְלָה מִירוּשָׁלַיִם עִם הַגֹּלָה אֲשֶׁר הָגְלְתָה עִם יְכָנְיָה מֶלֶךְ יְהוּדָה, אֲשֶׁר הֶגְלָה נְבוּכַדְנֶאצַּר מֶלֶךְ בָּבֶל: וַיְהִי אֹמֵן אֶת הֲדַסָּה הִיא אֶסְתֵּר בַּת דֹּדוֹ כִּי אֵין לָהּ אָב וָאֵם, וְהַנַּעֲרָה יְפַת תֹּאַר וְטוֹבַת מַרְאֶה וּבְמוֹת אָבִיהָ וְאִמָּהּ לְקָחָהּ מָרְדֳּכַי לוֹ לְבַת: וַיְהִי בְּהִשָּׁמַע דְּבַר הַמֶּלֶךְ וְדָתוֹ, וּבְהִקָּבֵץ נְעָרוֹת רַבּוֹת אֶל שׁוּשַׁן הַבִּירָה אֶל יַד הֵגָי, וַתִּלָּקַח אֶסְתֵּר אֶל בֵּית הַמֶּלֶךְ אֶל יַד הֵגַי שֹׁמֵר הַנָּשִׁים: וַתִּיטַב הַנַּעֲרָה בְעֵינָיו וַתִּשָּׂא חֶסֶד לְפָנָיו, וַיְבַהֵל אֶת תַּמְרוּקֶיהָ וְאֶת מָנוֹתֶהָ לָתֵת לָהּ, וְאֵת שֶׁבַע הַנְּעָרוֹת הָרְאֻיוֹת לָתֶת לָהּ מִבֵּית הַמֶּלֶךְ, וַיְשַׁנֶּהָ וְאֶת נַעֲרוֹתֶיהָ לְטוֹב בֵּית הַנָּשִׁים: לֹא הִגִּידָה אֶסְתֵּר אֶת עַמָּהּ וְאֶת מוֹלַדְתָּהּ, כִּי מָרְדֳּכַי צִוָּה עָלֶיהָ אֲשֶׁר לֹא תַגִּיד: וּבְכָל יוֹם וָיוֹם מָרְדֳּכַי מִתְהַלֵּךְ לִפְנֵי חֲצַר בֵּית הַנָּשִׁים, לָדַעַת אֶת שְׁלוֹם אֶסְתֵּר וּמַה יֵּעָשֶׂה בָּהּ: וּבְהַגִּיעַ תֹּר נַעֲרָה וְנַעֲרָה לָבוֹא אֶל הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, מִקֵּץ הֱיוֹת לָהּ כְּדָת הַנָּשִׁים שְׁנֵים עָשָׂר חֹדֶשׁ כִּי כֵּן יִמְלְאוּ יְמֵי מְרוּקֵיהֶן, שִׁשָּׁה חֳדָשִׁים בְּשֶׁמֶן הַמֹּר וְשִׁשָּׁה חֳדָשִׁים בַּבְּשָׂמִים וּבְתַמְרוּקֵי הַנָּשִׁים: וּבָזֶה הַנַּעֲרָה בָּאָה אֶל הַמֶּלֶךְ, אֵת כָּל אֲשֶׁר תֹּאמַר יִנָּתֵן לָהּ לָבוֹא עִמָּהּ מִבֵּית הַנָּשִׁים עַד בֵּית הַמֶּלֶךְ: בָּעֶרֶב הִיא בָאָה וּבַבֹּקֶר הִיא שָׁבָה אֶל בֵּית הַנָּשִׁים שֵׁנִי, אֶל יַד שַׁעֲשְׁגַז סְרִיס הַמֶּלֶךְ שֹׁמֵר הַפִּילַגְשִׁים, לֹא תָבוֹא עוֹד אֶל הַמֶּלֶךְ כִּי אִם חָפֵץ בָּהּ הַמֶּלֶךְ וְנִקְרְאָה בְשֵׁם: וּבְהַגִּיעַ תֹּר אֶסְתֵּר בַּת אֲבִיחַיִל דֹּד מָרְדֳּכַי אֲשֶׁר לָקַח לוֹ לְבַת לָבוֹא אֶל הַמֶּלֶךְ, לֹא בִקְשָׁה דָּבָר כִּי אִם אֶת אֲשֶׁר יֹאמַר הֵגַי סְרִיס הַמֶּלֶךְ שֹׁמֵר הַנָּשִׁים, וַתְּהִי אֶסְתֵּר נֹשֵׂאת חֵן בְּעֵינֵי כָּל רֹאֶיהָ: וַתִּלָּקַח אֶסְתֵּר אֶל הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ אֶל בֵּית מַלְכוּתוֹ בַּחֹדֶשׁ הָעֲשִׂירִי הוּא חֹדֶשׁ טֵבֵת, בִּשְׁנַת שֶׁבַע לְמַלְכוּתוֹ: וַיֶּאֱהַב הַמֶּלֶךְ אֶת אֶסְתֵּר מִכָּל הַנָּשִׁים וַתִּשָּׂא חֵן וָחֶסֶד לְפָנָיו מִכָּל הַבְּתוּלֹת, וַיָּשֶׂם כֶּתֶר מַלְכוּת בְּרֹאשָׁהּ וַיַּמְלִיכֶהָ תַּחַת וַשְׁתִּי: וַיַּעַשׂ הַמֶּלֶךְ מִשְׁתֶּה גָדוֹל לְכָל שָׂרָיו וַעֲבָדָיו, אֵת מִשְׁתֵּה אֶסְתֵּר, וַהֲנָחָה לַמְּדִינוֹת עָשָׂה וַיִּתֵּן מַשְׂאֵת כְּיַד הַמֶּלֶךְ: וּבְהִקָּבֵץ בְּתוּלוֹת שֵׁנִית, וּמָרְדֳּכַי יֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ: אֵין אֶסְתֵּר מַגֶּדֶת מוֹלַדְתָּהּ וְאֶת עַמָּהּ כַּאֲשֶׁר צִוָּה עָלֶיהָ מָרְדֳּכַי, וְאֶת מַאֲמַר מָרְדֳּכַי אֶסְתֵּר עֹשָׂה כַּאֲשֶׁר הָיְתָה בְאָמְנָה אִתּוֹ: בַּיָּמִים הָהֵם, וּמָרְדֳּכַי יֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ, קָצַף בִּגְתָן וָתֶרֶשׁ שְׁנֵי סָרִיסֵי הַמֶּלֶךְ מִשֹּׁמְרֵי הַסַּף וַיְבַקְשׁוּ לִשְׁלֹחַ יָד בַּמֶּלֶךְ אֲחַשְׁוֵרֹשׁ: וַיִּוָּדַע הַדָּבָר לְמָרְדֳּכַי וַיַּגֵּד לְאֶסְתֵּר הַמַּלְכָּה, וַתֹּאמֶר אֶסְתֵּר לַמֶּלֶךְ בְּשֵׁם מָרְדֳּכַי: וַיְבֻקַּשׁ הַדָּבָר וַיִּמָּצֵא וַיִּתָּלוּ שְׁנֵיהֶם עַל עֵץ, וַיִּכָּתֵב בְּסֵפֶר דִּבְרֵי הַיָּמִים לִפְנֵי הַמֶּלֶךְ:","cond":["megilatEster"]},{"kind":"header","text":"פרק ג'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ג'","cond":["megilatEster"]},{"kind":"text","text":"אַחַר הַדְּבָרִים הָאֵלֶּה גִּדַּל הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ אֶת הָמָן בֶּן הַמְּדָתָא הָאֲגָגִי וַיְנַשְּׂאֵהוּ, וַיָּשֶׂם אֶת כִּסְאוֹ מֵעַל כָּל הַשָּׂרִים אֲשֶׁר אִתּוֹ: וְכָל עַבְדֵי הַמֶּלֶךְ אֲשֶׁר בְּשַׁעַר הַמֶּלֶךְ כֹּרְעִים וּמִשְׁתַּחֲוִים לְהָמָן, כִּי כֵן צִוָּה לוֹ הַמֶּלֶךְ, וּמָרְדֳּכַי לֹא יִכְרַע וְלֹא יִשְׁתַּחֲוֶה: וַיֹּאמְרוּ עַבְדֵי הַמֶּלֶךְ אֲשֶׁר בְּשַׁעַר הַמֶּלֶךְ לְמָרְדֳּכַי, מַדּוּעַ אַתָּה עוֹבֵר אֵת מִצְוַת הַמֶּלֶךְ: וַיְהִי כְּאָמְרָם אֵלָיו יוֹם וָיוֹם וְלֹא שָׁמַע אֲלֵיהֶם, וַיַּגִּידוּ לְהָמָן לִרְאוֹת הֲיַעַמְדוּ דִּבְרֵי מָרְדֳּכַי כִּי הִגִּיד לָהֶם אֲשֶׁר הוּא יְהוּדִי: וַיַּרְא הָמָן כִּי אֵין מָרְדֳּכַי כֹּרֵעַ וּמִשְׁתַּחֲוֶה לוֹ, וַיִּמָּלֵא הָמָן חֵמָה: וַיִּבֶז בְּעֵינָיו לִשְׁלֹח יָד בְּמָרְדֳּכַי לְבַדּוֹ כִּי הִגִּידוּ לוֹ אֶת עַם מָרְדֳּכַי, וַיְבַקֵּשׁ הָמָן לְהַשְׁמִיד אֶת כָּל הַיְּהוּדִים אֲשֶׁר בְּכָל מַלְכוּת אֲחַשְׁוֵרוֹשׁ עַם מָרְדֳּכַי: בַּחֹדֶשׁ הָרִאשׁוֹן הוּא חֹדֶשׁ נִיסָן בִּשְׁנַת שְׁתֵּים עֶשְׂרֵה לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, הִפִּיל פּוּר הוּא הַגּוֹרָל לִפְנֵי הָמָן מִיּוֹם לְיוֹם וּמֵחֹדֶשׁ לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר: וַיֹּאמֶר הָמָן לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ יֶשְׁנוֹ עַם אֶחָד מְפֻזָּר וּמְפֹרָד בֵּין הָעַמִּים בְּכֹל מְדִינוֹת מַלְכוּתֶךָ, וְדָתֵיהֶם שֹׁנוֹת מִכָּל עָם וְאֶת דָּתֵי הַמֶּלֶךְ אֵינָם עֹשִׂים וְלַמֶּלֶךְ אֵין שֹׁוֶה לְהַנִּיחָם: אִם עַל הַמֶּלֶךְ טוֹב יִכָּתֵב לְאַבְּדָם, וַעֲשֶׂרֶת אֲלָפִים כִּכַּר כֶּסֶף אֶשְׁקוֹל עַל יְדֵי עֹשֵׂי הַמְּלָאכָה לְהָבִיא אֶל גִּנְזֵי הַמֶּלֶךְ: וַיָּסַר הַמֶּלֶךְ אֶת טַבַּעְתּוֹ מֵעַל יָדוֹ, וַיִּתְּנָהּ לְהָמָן בֶּן הַמְּדָתָא הָאֲגָגִי צֹרֵר הַיְּהוּדִים: וַיֹּאמֶר הַמֶּלֶךְ לְהָמָן הַכֶּסֶף נָתוּן לָךְ, וְהָעָם לַעֲשׂוֹת בּוֹ כַּטּוֹב בְּעֵינֶיךָ: וַיִּקָּרְאוּ סֹפְרֵי הַמֶּלֶךְ בַּחֹדֶשׁ הָרִאשׁוֹן בִּשְׁלוֹשָׁה עָשָׂר יוֹם בּוֹ, וַיִּכָּתֵב כְּכָל אֲשֶׁר צִוָּה הָמָן אֶל אֲחַשְׁדַּרְפְּנֵי הַמֶּלֶךְ וְאֶל הַפַּחוֹת אֲשֶׁר עַל מְדִינָה וּמְדִינָה וְאֶל שָׂרֵי עַם וָעָם, מְדִינָה וּמְדִינָה כִּכְתָבָהּ וְעַם וָעָם כִּלְשׁוֹנוֹ, בְּשֵׁם הַמֶּלֶךְ אֲחַשְׁוֵרֹשׁ נִכְתָּב וְנֶחְתָּם בְּטַבַּעַת הַמֶּלֶךְ: וְנִשְׁלוֹחַ סְפָרִים בְּיַד הָרָצִים אֶל כָּל מְדִינוֹת הַמֶּלֶךְ, לְהַשְׁמִיד לַהֲרֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלוֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: פַּתְשֶׁגֶן הַכְּתָב לְהִנָּתֵן דָּת בְּכָל מְדִינָה וּמְדִינָה גָּלוּי לְכָל הָעַמִּים, לִהְיוֹת עֲתִדִים לַיּוֹם הַזֶּה: הָרָצִים יָצְאוּ דְחוּפִים בִּדְבַר הַמֶּלֶךְ וְהַדָּת נִתְּנָה בְּשׁוּשַׁן הַבִּירָה, וְהַמֶּלֶךְ וְהָמָן יָשְׁבוּ לִשְׁתּוֹת וְהָעִיר שׁוּשָׁן נָבוֹכָה:","cond":["megilatEster"]},{"kind":"header","text":"פרק ד'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ד'","cond":["megilatEster"]},{"kind":"text","text":"וּמָרְדֳּכַי יָדַע אֶת כָּל אֲשֶׁר נַעֲשָׂה וַיִּקְרַע מָרְדֳּכַי אֶת בְּגָדָיו וַיִּלְבַּשׁ שַׂק וָאֵפֶר, וַיֵּצֵא בְּתוֹךְ הָעִיר וַיִּזְעַק זְעָקָה גְדֹלָה וּמָרָה: וַיָּבוֹא עַד לִפְנֵי שַׁעַר הַמֶּלֶךְ, כִּי אֵין לָבוֹא אֶל שַׁעַר הַמֶּלֶךְ בִּלְבוּשׁ שָׂק: וּבְכָל מְדִינָה וּמְדִינָה מְקוֹם אֲשֶׁר דְּבַר הַמֶּלֶךְ וְדָתוֹ מַגִּיעַ, אֵבֶל גָּדוֹל לַיְּהוּדִים וְצוֹם וּבְכִי וּמִסְפֵּד, שַׂק וָאֵפֶר יֻצַּע לָרַבִּים: וַתָּבוֹאנָה נַעֲרוֹת אֶסְתֵּר וְסָרִיסֶיהָ וַיַּגִּידוּ לָהּ וַתִּתְחַלְחַל הַמַּלְכָּה מְאֹד, וַתִּשְׁלַח בְּגָדִים לְהַלְבִּישׁ אֶת מָרְדֳּכַי וּלְהָסִיר שַׂקּוֹ מֵעָלָיו וְלֹא קִבֵּל: וַתִּקְרָא אֶסְתֵּר לַהֲתָךְ מִסָּרִיסֵי הַמֶּלֶךְ אֲשֶׁר הֶעֱמִיד לְפָנֶיהָ וַתְּצַוֵּהוּ עַל מָרְדֳּכַי, לָדַעַת מַה זֶּה וְעַל מַה זֶּה: וַיֵּצֵא הֲתָךְ אֶל מָרְדֳּכַי, אֶל רְחוֹב הָעִיר אֲשֶׁר לִפְנֵי שַׁעַר הַמֶּלֶךְ: וַיַּגֶּד לוֹ מָרְדֳּכַי אֵת כָּל אֲשֶׁר קָרָהוּ, וְאֵת פָּרָשַׁת הַכֶּסֶף אֲשֶׁר אָמַר הָמָן לִשְׁקוֹל עַל גִּנְזֵי הַמֶּלֶךְ בַּיְּהוּדִים לְאַבְּדָם: וְאֶת פַּתְשֶׁגֶן כְּתָב הַדָּת אֲשֶׁר נִתַּן בְּשׁוּשָׁן לְהַשְׁמִידָם נָתַן לוֹ לְהַרְאוֹת אֶת אֶסְתֵּר וּלְהַגִּיד לָהּ, וּלְצַוּוֹת עָלֶיהָ לָבוֹא אֶל הַמֶּלֶךְ לְהִתְחַנֶּן לוֹ וּלְבַקֵּשׁ מִלְּפָנָיו עַל עַמָּהּ: וַיָּבוֹא הֲתָךְ, וַיַּגֵּד לְאֶסְתֵּר אֵת דִּבְרֵי מָרְדֳּכַי: וַתֹּאמֶר אֶסְתֵּר לַהֲתָךְ, וַתְּצַוֵּהוּ אֶל מָרְדֳּכַי: כָּל עַבְדֵי הַמֶּלֶךְ וְעַם מְדִינוֹת הַמֶּלֶךְ יוֹדְעִים אֲשֶׁר כָּל אִישׁ וְאִשָּׁה אֲשֶׁר יָבוֹא אֶל הַמֶּלֶךְ אֶל הֶחָצֵר הַפְּנִימִית אֲשֶׁר לֹא יִקָּרֵא אַחַת דָּתוֹ לְהָמִית, לְבַד מֵאֲשֶׁר יוֹשִׁיט לוֹ הַמֶּלֶךְ אֶת שַׁרְבִיט הַזָּהָב וְחָיָה, וַאֲנִי לֹא נִקְרֵאתִי לָבוֹא אֶל הַמֶּלֶךְ זֶה שְׁלוֹשִׁים יוֹם: וַיַּגִּידוּ לְמָרְדֳּכַי אֵת דִּבְרֵי אֶסְתֵּר: וַיֹּאמֶר מָרְדֳּכַי לְהָשִׁיב אֶל אֶסְתֵּר, אַל תְּדַמִּי בְנַפְשֵׁךְ לְהִמָּלֵט בֵּית הַמֶּלֶךְ מִכָּל הַיְּהוּדִים: כִּי אִם הַחֲרֵשׁ תַּחֲרִישִׁי בָּעֵת הַזֹּאת, רֶוַח וְהַצָּלָה יַעֲמוֹד לַיְּהוּדִים מִמָּקוֹם אַחֵר וְאַתְּ וּבֵית אָבִיךְ תֹּאבֵדוּ, וּמִי יוֹדֵעַ אִם לְעֵת כָּזֹאת הִגַּעַתְּ לַמַּלְכוּת: וַתֹּאמֶר אֶסְתֵּר לְהָשִׁיב אֶל מָרְדֳּכַי: לֵךְ כְּנוֹס אֶת כָּל הַיְּהוּדִים הַנִּמְצְאִים בְּשׁוּשָׁן וְצוּמוּ עָלַי וְאַל תֹּאכְלוּ וְאַל תִּשְׁתּוּ שְׁלֹשֶׁת יָמִים לַיְלָה וָיוֹם, גַּם אֲנִי וְנַעֲרֹתַי אָצוּם כֵּן, וּבְכֵן אָבוֹא אֶל הַמֶּלֶךְ אֲשֶׁר לֹא כַדָּת וְכַאֲשֶׁר אָבַדְתִּי אָבָדְתִּי: וַיַּעֲבֹר מָרְדֳּכַי, וַיַּעַשׂ כְּכֹל אֲשֶׁר צִוְּתָה עָלָיו אֶסְתֵּר:","cond":["megilatEster"]},{"kind":"header","text":"פרק ה'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ה'","cond":["megilatEster"]},{"kind":"text","text":"וַיְהִי בַּיּוֹם הַשְּׁלִישִׁי וַתִּלְבַּשׁ אֶסְתֵּר מַלְכוּת, וַתַּעֲמֹד בַּחֲצַר בֵּית הַמֶּלֶךְ הַפְּנִימִית נֹכַח בֵּית הַמֶּלֶךְ, וְהַמֶּלֶךְ יוֹשֵׁב עַל כִּסֵּא מַלְכוּתוֹ בְּבֵית הַמַּלְכוּת נֹכַח פֶּתַח הַבָּיִת: וַיְהִי כִרְאוֹת הַמֶּלֶךְ אֶת אֶסְתֵּר הַמַּלְכָּה עֹמֶדֶת בֶּחָצֵר נָשְׂאָה חֵן בְּעֵינָיו, וַיּוֹשֶׁט הַמֶּלֶךְ לְאֶסְתֵּר אֶת שַׁרְבִיט הַזָּהָב אֲשֶׁר בְּיָדוֹ, וַתִּקְרַב אֶסְתֵּר וַתִּגַּע בְּרֹאשׁ הַשַּׁרְבִיט: וַיֹּאמֶר לָהּ הַמֶּלֶךְ מַה לָּךְ אֶסְתֵּר הַמַּלְכָּה, וּמַה בַּקָּשָׁתֵךְ עַד חֲצִי הַמַּלְכוּת וְיִנָּתֵן לָךְ: וַתֹּאמֶר אֶסְתֵּר אִם עַל הַמֶּלֶךְ טוֹב, יָבוֹא הַמֶּלֶךְ וְהָמָן הַיּוֹם אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשִׂיתִי לוֹ: וַיֹּאמֶר הַמֶּלֶךְ מַהֲרוּ אֶת הָמָן לַעֲשׂוֹת אֶת דְּבַר אֶסְתֵּר, וַיָּבֹא הַמֶּלֶךְ וְהָמָן אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשְׂתָה אֶסְתֵּר: וַיֹּאמֶר הַמֶּלֶךְ לְאֶסְתֵּר בְּמִשְׁתֵּה הַיַּיִן מַה שְּׁאֵלָתֵךְ וְיִנָּתֵן לָךְ, וּמַה בַּקָּשָׁתֵךְ עַד חֲצִי הַמַּלְכוּת וְתֵעָשׂ: וַתַּעַן אֶסְתֵּר וַתֹּאמַר, שְׁאֵלָתִי וּבַקָּשָׁתִי: אִם מָצָאתִי חֵן בְּעֵינֵי הַמֶּלֶךְ וְאִם עַל הַמֶּלֶךְ טוֹב לָתֵת אֶת שְׁאֵלָתִי וְלַעֲשׂוֹת אֶת בַּקָּשָׁתִי, יָבוֹא הַמֶּלֶךְ וְהָמָן אֶל הַמִּשְׁתֶּה אֲשֶׁר אֶעֱשֶׂה לָהֶם וּמָחָר אֶעֱשֶׂה כִּדְבַר הַמֶּלֶךְ: וַיֵּצֵא הָמָן בַּיּוֹם הַהוּא שָׂמֵחַ וְטוֹב לֵב, וְכִרְאוֹת הָמָן אֶת מָרְדֳּכַי בְּשַׁעַר הַמֶּלֶךְ וְלֹא קָם וְלֹא זָע מִמֶּנּוּ וַיִּמָּלֵא הָמָן עַל מָרְדֳּכַי חֵמָה: וַיִּתְאַפַּק הָמָן וַיָּבוֹא אֶל בֵּיתוֹ, וַיִּשְׁלַח וַיָּבֵא אֶת אֹהֲבָיו וְאֶת זֶרֶשׁ אִשְׁתּוֹ: וַיְסַפֵּר לָהֶם הָמָן אֶת כְּבוֹד עָשְׁרוֹ וְרֹב בָּנָיו, וְאֵת כָּל אֲשֶׁר גִּדְּלוֹ הַמֶּלֶךְ וְאֵת אֲשֶׁר נִשְּׂאוֹ עַל הַשָּׂרִים וְעַבְדֵי הַמֶּלֶךְ: וַיֹּאמֶר הָמָן, אַף לֹא הֵבִיאָה אֶסְתֵּר הַמַּלְכָּה עִם הַמֶּלֶךְ אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשָׂתָה כִּי אִם אוֹתִי, וְגַם לְמָחָר אֲנִי קָרוּא לָהּ עִם הַמֶּלֶךְ: וְכָל זֶה אֵינֶנּוּ שֹׁוֶה לִי, בְּכָל עֵת אֲשֶׁר אֲנִי רֹאֶה אֶת מָרְדֳּכַי הַיְּהוּדִי יוֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ: וַתֹּאמֶר לוֹ זֶרֶשׁ אִשְׁתּוֹ וְכָל אֹהֲבָיו יַעֲשׂוּ עֵץ גָּבֹהַּ חֲמִשִּׁים אַמָּה, וּבַבֹּקֶר אֱמֹר לַמֶּלֶךְ וְיִתְלוּ אֶת מָרְדֳּכַי עָלָיו וּבֹא עִם הַמֶּלֶךְ אֶל הַמִּשְׁתֶּה שָׂמֵחַ, וַיִּיטַב הַדָּבָר לִפְנֵי הָמָן וַיַּעַשׂ הָעֵץ:","cond":["megilatEster"]},{"kind":"header","text":"פרק ו'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ו'","cond":["megilatEster"]},{"kind":"special","text":"בַּלַּיְלָה הַהוּא נָדְדָה שְׁנַת הַמֶּלֶךְ, וַיֹּאמֶר לְהָבִיא אֶת סֵפֶר הַזִּכְרֹנוֹת דִּבְרֵי הַיָּמִים, וַיִּהְיוּ נִקְרָאִים לִפְנֵי הַמֶּלֶךְ:","cond":["megilatEster"]},{"kind":"text","text":"וַיִּמָּצֵא כָתוּב אֲשֶׁר הִגִּיד מָרְדֳּכַי עַל בִּגְתָנָא וָתֶרֶשׁ שְׁנֵי סָרִיסֵי הַמֶּלֶךְ מִשֹּׁמְרֵי הַסַּף אֲשֶׁר בִּקְשׁוּ לִשְׁלֹחַ יָד בַּמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: וַיֹּאמֶר הַמֶּלֶךְ מַה נַּעֲשָׂה יְקָר וּגְדוּלָּה לְמָרְדֳּכַי עַל זֶה, וַיֹּאמְרוּ נַעֲרֵי הַמֶּלֶךְ מְשָׁרְתָיו לֹא נַעֲשָׂה עִמּוֹ דָּבָר: וַיֹּאמֶר הַמֶּלֶךְ מִי בֶחָצֵר, וְהָמָן בָּא לַחֲצַר בֵּית הַמֶּלֶךְ הַחִיצוֹנָה לֵאמֹר לַמֶּלֶךְ לִתְלוֹת אֶת מָרְדֳּכַי עַל הָעֵץ אֲשֶׁר הֵכִין לוֹ: וַיֹּאמְרוּ נַעֲרֵי הַמֶּלֶךְ אֵלָיו הִנֵּה הָמָן עֹמֵד בֶּחָצֵר, וַיֹּאמֶר הַמֶּלֶךְ יָבוֹא: וַיָּבוֹא הָמָן, וַיֹּאמֶר לוֹ הַמֶּלֶךְ מַה לַעֲשׂוֹת בָּאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ, וַיֹּאמֶר הָמָן בְּלִבּוֹ לְמִי יַחְפֹּץ הַמֶּלֶךְ לַעֲשׂוֹת יְקָר יוֹתֵר מִמֶּנִּי: וַיֹּאמֶר הָמָן אֶל הַמֶּלֶךְ, אִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ: יָבִיאוּ לְבוּשׁ מַלְכוּת אֲשֶׁר לָבַשׁ בּוֹ הַמֶּלֶךְ, וְסוּס אֲשֶׁר רָכַב עָלָיו הַמֶּלֶךְ וַאֲשֶׁר נִתַּן כֶּתֶר מַלְכוּת בְּרֹאשׁוֹ: וְנָתוֹן הַלְּבוּשׁ וְהַסּוּס עַל יַד אִישׁ מִשָּׂרֵי הַמֶּלֶךְ הַפַּרְתְּמִים וְהִלְבִּישׁוּ אֶת הָאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ, וְהִרְכִּיבֻהוּ עַל הַסּוּס בִּרְחוֹב הָעִיר וְקָרְאוּ לְפָנָיו כָּכָה יֵעָשֶׂה לָאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ: וַיֹּאמֶר הַמֶּלֶךְ לְהָמָן מַהֵר קַח אֶת הַלְּבוּשׁ וְאֶת הַסּוּס כַּאֲשֶׁר דִּבַּרְתָּ וַעֲשֵׂה כֵן לְמָרְדֳּכַי הַיְּהוּדִי הַיּוֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ, אַל תַּפֵּל דָּבָר מִכֹּל אֲשֶׁר דִּבַּרְתָּ: וַיִּקַּח הָמָן אֶת הַלְּבוּשׁ וְאֶת הַסּוּס וַיַּלְבֵּשׁ אֶת מָרְדֳּכַי, וַיַּרְכִּיבֵהוּ בִּרְחוֹב הָעִיר וַיִּקְרָא לְפָנָיו כָּכָה יֵעָשֶׂה לָאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ: וַיָּשָָב מָרְדֳּכַי אֶל שַׁעַר הַמֶּלֶךְ, וְהָמָן נִדְחַף אֶל בֵּיתוֹ אָבֵל וַחֲפוּי רֹאשׁ: וַיְסַפֵּר הָמָן לְזֶרֶשׁ אִשְׁתּוֹ וּלְכָל אֹהֲבָיו אֵת כָּל אֲשֶׁר קָרָהוּ, וַיֹּאמְרוּ לּוֹ חֲכָמָיו וְזֶרֶשׁ אִשְׁתּוֹ אִם מִזֶּרַע הַיְּהוּדִים מָרְדֳּכַי אֲשֶׁר הַחִלּוֹתָ לִנְפֹּל לְפָנָיו לֹא תוּכַל לוֹ, כִּי נָפוֹל תִּפּוֹל לְפָנָיו: עוֹדָם מְדַבְּרִים עִמּוֹ וְסָרִיסֵי הַמֶּלֶךְ הִגִּיעוּ, וַיַּבְהִלוּ לְהָבִיא אֶת הָמָן אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשְׂתָה אֶסְתֵּר:","cond":["megilatEster"]},{"kind":"header","text":"פרק ז'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ז'","cond":["megilatEster"]},{"kind":"text","text":"וַיָּבֹא הַמֶּלֶךְ וְהָמָן לִשְׁתּוֹת עִם אֶסְתֵּר הַמַּלְכָּה: וַיֹּאמֶר הַמֶּלֶךְ לְאֶסְתֵּר גַּם בַּיּוֹם הַשֵּׁנִי בְּמִשְׁתֵּה הַיַּיִן מַה שְּׁאֵלָתֵךְ אֶסְתֵּר הַמַּלְכָּה וְתִנָּתֵן לָךְ, וּמַה בַּקָּשָׁתֵךְ עַד חֲצִי הַמַּלְכוּת וְתֵעָשׂ: וַתַּעַן אֶסְתֵּר הַמַּלְכָּה וַתֹּאמַר אִם מָצָאתִי חֵן בְּעֵינֶיךָ הַמֶּלֶךְ וְאִם עַל הַמֶּלֶךְ טוֹב, תִּנָּתֶן לִי נַפְשִׁי בִּשְׁאֵלָתִי וְעַמִּי בְּבַקָּשָׁתִי: כִּי נִמְכַּרְנוּ אֲנִי וְעַמִּי לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד, וְאִלּוּ לַעֲבָדִים וְלִשְׁפָחוֹת נִמְכַּרְנוּ הֶחֱרַשְׁתִּי כִּי אֵין הַצָּר שֹׁוֶה בְּנֵזֶק הַמֶּלֶךְ: וַיֹּאמֶר הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ וַיֹּאמֶר לְאֶסְתֵּר הַמַּלְכָּה, מִי הוּא זֶה וְאֵי זֶה הוּא אֲשֶׁר מְלָאוֹ לִבּוֹ לַעֲשׂוֹת כֵּן: וַתֹּאמֶר אֶסְתֵּר אִישׁ צַר וְאוֹיֵב הָמָן הָרָע הַזֶּה, וְהָמָן נִבְעַת מִלִּפְנֵי הַמֶּלֶךְ וְהַמַּלְכָּה: וְהַמֶּלֶךְ קָם בַּחֲמָתוֹ מִמִּשְׁתֵּה הַיַּיִן אֶל גִּנַּת הַבִּיתָן, וְהָמָן עָמַד לְבַקֵּשׁ עַל נַפְשׁוֹ מֵאֶסְתֵּר הַמַּלְכָּה כִּי רָאָה כִּי כָלְתָה אֵלָיו הָרָעָה מֵאֵת הַמֶּלֶךְ: וְהַמֶּלֶךְ שָׁב מִגִּנַּת הַבִּיתָן אֶל בֵּית מִשְׁתֵּה הַיַּיִן וְהָמָן נֹפֵל עַל הַמִּטָּה אֲשֶׁר אֶסְתֵּר עָלֶיהָ, וַיֹּאמֶר הַמֶּלֶךְ הֲגַם לִכְבּוֹשׁ אֶת הַמַּלְכָּה עִמִּי בַּבָּיִת, הַדָּבָר יָצָא מִפִּי הַמֶּלֶךְ וּפְנֵי הָמָן חָפוּ: וַיֹּאמֶר חַרְבוֹנָה אֶחָד מִן הַסָּרִיסִים לִפְנֵי הַמֶּלֶךְ גַּם הִנֵּה הָעֵץ אֲשֶׁר עָשָׂה הָמָן לְמָרְדֳּכַי אֲשֶׁר דִּבֶּר טוֹב עַל הַמֶּלֶךְ עֹמֵד בְּבֵית הָמָן גָּבֹהַּ חֲמִשִּׁים אַמָּה, וַיֹּאמֶר הַמֶּלֶךְ תְּלֻהוּ עָלָיו: וַיִּתְלוּ אֶת הָמָן עַל הָעֵץ אֲשֶׁר הֵכִין לְמָרְדֳּכַי, וַחֲמַת הַמֶּלֶךְ שָׁכָכָה:","cond":["megilatEster"]},{"kind":"header","text":"פרק ח'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ח'","cond":["megilatEster"]},{"kind":"text","text":"בַּיּוֹם הַהוּא נָתַן הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ לְאֶסְתֵּר הַמַּלְכָּה אֶת בֵּית הָמָן צֹרֵר הַיְּהוּדִים, וּמָרְדֳּכַי בָּא לִפְנֵי הַמֶּלֶךְ כִּי הִגִּידָה אֶסְתֵּר מַה הוּא לָהּ: וַיָּסַר הַמֶּלֶךְ אֶת טַבַּעְתּוֹ אֲשֶׁר הֶעֱבִיר מֵהָמָן וַיִּתְּנָהּ לְמָרְדֳּכַי, וַתָּשֶׂם אֶסְתֵּר אֶת מָרְדֳּכַי עַל בֵּית הָמָן: וַתּוֹסֶף אֶסְתֵּר וַתְּדַבֵּר לִפְנֵי הַמֶּלֶךְ וַתִּפֹּל לִפְנֵי רַגְלָיו, וַתֵּבְךְּ וַתִּתְחַנֶּן לוֹ לְהַעֲבִיר אֶת רָעַת הָמָן הָאֲגָגִי וְאֵת מַחֲשַׁבְתּוֹ אֲשֶׁר חָשַׁב עַל הַיְּהוּדִים: וַיּוֹשֶׁט הַמֶּלֶךְ לְאֶסְתֵּר אֵת שַׁרְבִט הַזָּהָב, וַתָּקָם אֶסְתֵּר וַתַּעֲמֹד לִפְנֵי הַמֶּלֶךְ: וַתֹּאמֶר אִם עַל הַמֶּלֶךְ טוֹב וְאִם מָצָאתִי חֵן לְפָנָיו וְכָשֵׁר הַדָּבָר לִפְנֵי הַמֶּלֶךְ וְטוֹבָה אֲנִי בְּעֵינָיו, יִכָּתֵב לְהָשִׁיב אֶת הַסְּפָרִים מַחֲשֶׁבֶת הָמָן בֶּן הַמְּדָתָא הָאֲגָגִי אֲשֶׁר כָּתַב לְאַבֵּד אֶת הַיְּהוּדִים אֲשֶׁר בְּכָל מְדִינוֹת הַמֶּלֶךְ: כִּי אֵיכָכָה אוּכַל וְרָאִיתִי בָּרָעָה אֲשֶׁר יִמְצָא אֶת עַמִּי, וְאֵיכָכָה אוּכַל וְרָאִיתִי בְּאָבְדַן מוֹלַדְתִּי: וַיֹּאמֶר הַמֶּלֶךְ אֲחַשְׁוֵרֹשׁ לְאֶסְתֵּר הַמַּלְכָּה וּלְמָרְדֳּכַי הַיְּהוּדִי, הִנֵּה בֵית הָמָן נָתַתִּי לְאֶסְתֵּר וְאֹתוֹ תָּלוּ עַל הָעֵץ עַל אֲשֶׁר שָׁלַח יָדוֹ בַּיְּהוּדִים: וְאַתֶּם כִּתְבוּ עַל הַיְּהוּדִים כַּטּוֹב בְּעֵינֵיכֶם בְּשֵׁם הַמֶּלֶךְ וְחִתְמוּ בְּטַבַּעַת הַמֶּלֶךְ, כִּי כְתָב אֲשֶׁר נִכְתָּב בְּשֵׁם הַמֶּלֶךְ וְנַחְתּוֹם בְּטַבַּעַת הַמֶּלֶךְ אֵין לְהָשִׁיב: וַיִּקָּרְאוּ סֹפְרֵי הַמֶּלֶךְ בָּעֵת הַהִיא בַּחֹדֶשׁ הַשְּׁלִישִׁי הוּא חֹדֶשׁ סִיוָן בִּשְׁלוֹשָׁה וְעֶשְׂרִים בּוֹ, וַיִּכָּתֵב כְּכָל אֲשֶׁר צִוָּה מָרְדֳּכַי אֶל הַיְּהוּדִים וְאֶל הָאֲחַשְׁדַּרְפְּנִים וְהַפַּחוֹת וְשָׂרֵי הַמְּדִינוֹת אֲשֶׁר מֵהֹדּוּ וְעַד כּוּשׁ, שֶׁבַע וְעֶשְׂרִים וּמֵאָה מְדִינָה, מְדִינָה וּמְדִינָה כִּכְתָבָהּ וְעַם וָעָם כִּלְשֹׁנוֹ, וְאֶל הַיְּהוּדִים כִּכְתָבָם וְכִלְשׁוֹנָם: וַיִּכְתֹּב בְּשֵׁם הַמֶּלֶךְ אֲחַשְׁוֵרֹשׁ וַיַּחְתֹּם בְּטַבַּעַת הַמֶּלֶךְ, וַיִּשְׁלַח סְפָרִים בְּיַד הָרָצִים בַּסּוּסִים רֹכְבֵי הָרֶכֶשׁ הָאֲחַשְׁתְּרָנִים בְּנֵי הָרַמָּכִים: אֲשֶׁר נָתַן הַמֶּלֶךְ לַיְּהוּדִים אֲשֶׁר בְּכָל עִיר וָעִיר לְהִקָּהֵל וְלַעֲמֹד עַל נַפְשָׁם, לְהַשְׁמִיד וְלַהֲרֹג וּלְאַבֵּד אֶת כָּל חֵיל עַם וּמְדִינָה הַצָּרִים אֹתָם טַף וְנָשִׁים, וּשְׁלָלָם לָבוֹז: בְּיוֹם אֶחָד בְּכָל מְדִינוֹת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, בִּשְׁלוֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר: פַּתְשֶׁגֶן הַכְּתָב לְהִנָּתֵן דָּת בְּכָל מְדִינָה וּמְדִינָה גָּלוּי לְכָל הָעַמִּים, וְלִהְיוֹת הַיְּהוּדִים עֲתִידִים לַיּוֹם הַזֶּה לְהִנָּקֵם מֵאֹיְבֵיהֶם: הָרָצִים רֹכְבֵי הָרֶכֶשׁ הָאֲחַשְׁתְּרָנִים יָצְאוּ מְבֹהָלִים וּדְחוּפִים בִּדְבַר הַמֶּלֶךְ, וְהַדָּת נִתְּנָה בְּשׁוּשַׁן הַבִּירָה:","cond":["megilatEster"]},{"kind":"special","text":"וּמָרְדֳּכַי יָצָא מִלִּפְנֵי הַמֶּלֶךְ בִּלְבוּשׁ מַלְכוּת תְּכֵלֶת וָחוּר וַעֲטֶרֶת זָהָב גְּדוֹלָה וְתַכְרִיךְ בּוּץ וְאַרְגָּמָן, וְהָעִיר שׁוּשָׁן צָהֲלָה וְשָׂמֵחָה: לַיְּהוּדִים הָיְתָה אוֹרָה וְשִׂמְחָה, וְשָׂשֹׂן וִיקָר:","cond":["megilatEster"]},{"kind":"text","text":"וּבְכָל מְדִינָה וּמְדִינָה וּבְכָל עִיר וָעִיר, מְקוֹם אֲשֶׁר דְּבַר הַמֶּלֶךְ וְדָתוֹ מַגִּיעַ, שִׂמְחָה וְשָׂשׂוֹן לַיְּהוּדִים מִשְׁתֶּה וְיוֹם טוֹב, וְרַבִּים מֵעַמֵּי הָאָרֶץ מִתְיַהֲדִים כִּי נָפַל פַּחַד הַיְּהוּדִים עֲלֵיהֶם:","cond":["megilatEster"]},{"kind":"header","text":"פרק ט'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק ט'","cond":["megilatEster"]},{"kind":"text","text":"וּבִשְׁנֵים עָשָׂר חֹדֶשׁ הוּא חֹדֶשׁ אֲדָר בִּשְׁלוֹשָׁה עָשָׂר יוֹם בּוֹ אֲשֶׁר הִגִּיעַ דְּבַר הַמֶּלֶךְ וְדָתוֹ לְהֵעָשׂוֹת, בַּיּוֹם אֲשֶׁר שִׂבְּרוּ אֹיְבֵי הַיְּהוּדִים לִשְׁלוֹט בָּהֶם וְנַהֲפוֹךְ הוּא אֲשֶׁר יִשְׁלְטוּ הַיְּהוּדִים הֵמָּה בְּשֹׂנְאֵיהֶם: נִקְהֲלוּ הַיְּהוּדִים בְּעָרֵיהֶם בְּכָל מְדִינוֹת הַמֶּלֶךְ אֳחַשְׁוֵרוֹשׁ לִשְׁלֹחַ יָד בִּמְבַקְשֵׁי רָעָתָם, וְאִישׁ לֹא עָמַד לִפְנֵיהֶם כִּי נָפַל פַּחְדָּם עַל כָּל הָעַמִּים: וְכָל שָׂרֵי הַמְּדִינוֹת וְהָאֲחַשְׁדַּרְפְּנִים וְהַפַּחוֹת וְעֹשֵׂי הַמְּלָאכָה אֲשֶׁר לַמֶּלֶךְ מְנַשְּׂאִים אֶת הַיְּהוּדִים, כִּי נָפַל פַּחַד מָרְדֳּכַי עֲלֵיהֶם: כִּי גָדוֹל מָרְדֳּכַי בְּבֵית הַמֶּלֶךְ וְשָׁמְעוֹ הוֹלֵךְ בְּכָל הַמְּדִינוֹת, כִּי הָאִישׁ מָרְדֳּכַי הוֹלֵךְ וְגָדוֹל: וַיַּכּוּ הַיְּהוּדִים בְּכָל אֹיְבֵיהֶם מַכַּת חֶרֶב וְהֶרֶג וְאַבְדָן, וַיַּעֲשׂוּ בְשֹׂנְאֵיהֶם כִּרְצוֹנָם: וּבְשׁוּשַׁן הַבִּירָה הָרְגוּ הַיְּהוּדִים וְאַבֵּד חֲמֵשׁ מֵאוֹת אִישׁ: וְאֵת פַּרְשַׁנְדָּתָא וְאֵת דַּלְפוֹן וְאֵת אַסְפָּתָא: וְאֵת פּוֹרָתָא וְאֵת אֲדַלְיָא וְאֵת אֲרִידָתָא: וְאֵת פַּרְמַשְׁתָּא וְאֵת אֲרִיסַי וְאֵת אֲרִדַי וְאֵת וַיְזָתָא: עֲשֶׂרֶת בְּנֵי הָמָן בֶּן הַמְּדָתָא צֹרֵר הַיְּהוּדִים הָרָגוּ, וּבַבִּזָּה לֹא שָׁלְחוּ אֶת יָדָם: בַּיּוֹם הַהוּא בָּא מִסְפַּר הַהֲרוּגִים בְּשׁוּשַׁן הַבִּירָה לִפְנֵי הַמֶּלֶךְ: וַיֹּאמֶר הַמֶּלֶךְ לְאֶסְתֵּר הַמַּלְכָּה בְּשׁוּשַׁן הַבִּירָה הָרְגוּ הַיְּהוּדִים וְאַבֵּד חֲמֵשׁ מֵאוֹת אִישׁ וְאֵת עֲשֶׂרֶת בְּנֵי הָמָן, בִּשְׁאָר מְדִינוֹת הַמֶּלֶךְ מֶה עָשׂוּ, וּמַה שְּׁאֵלָתֵךְ וְיִנָּתֵן לָךְ וּמַה בַּקָּשָׁתֵךְ עוֹד וְתֵעָשׂ: וַתֹּאמֶר אֶסְתֵּר אִם עַל הַמֶּלֶךְ טוֹב, יִנָּתֵן גַּם מָחָר לַיְּהוּדִים אֲשֶׁר בְּשׁוּשָׁן לַעֲשׂוֹת כְּדָת הַיּוֹם, וְאֵת עֲשֶׂרֶת בְּנֵי הָמָן יִתְלוּ עַל הָעֵץ: וַיֹּאמֶר הַמֶּלֶךְ לְהֵעָשׂוֹת כֵּן וַתִּנָּתֵן דָּת בְּשׁוּשָׁן, וְאֵת עֲשֶׂרֶת בְּנֵי הָמָן תָּלוּ: וַיִּקָּהֲלוּ הַיְּהוּדִים אֲשֶׁר בְּשׁוּשָׁן גַּם בְּיוֹם אַרְבָּעָה עָשָׂר לְחֹדֶשׁ אֲדָר וַיַּהַרְגוּ בְשׁוּשָׁן שְׁלֹשׁ מֵאוֹת אִישׁ, וּבַבִּזָּה לֹא שָׁלְחוּ אֶת יָדָם: וּשְׁאָר הַיְּהוּדִים אֲשֶׁר בִּמְדִינוֹת הַמֶּלֶךְ נִקְהֲלוּ וְעָמֹד עַל נַפְשָׁם וְנוֹחַ מֵאֹיְבֵיהֶם וְהָרֹג בְּשֹׂנְאֵיהֶם חֲמִשָּׁה וְשִׁבְעִים אָלֶף, וּבַבִּזָּה לֹא שָׁלְחוּ אֶת יָדָם: בְּיוֹם שְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ אֲדָר, וְנוֹחַ בְּאַרְבָּעָה עָשָׂר בּוֹ וְעָשֹׂה אֹתוֹ יוֹם מִשְׁתֶּה וְשִׂמְחָה: וְהַיְּהוּדִים אֲשֶׁר בְּשׁוּשָׁן נִקְהֲלוּ בִּשְׁלֹשָׁה עָשָׂר בּוֹ וּבְאַרְבָּעָה עָשָׂר בּוֹ, וְנוֹחַ בַּחֲמִשָּׁה עָשָׂר בּוֹ וְעָשֹׂה אֹתוֹ יוֹם מִשְׁתֶּה וְשִׂמְחָה: עַל כֵּן הַיְּהוּדִים הַפְּרָזִים הַיֹּשְׁבִים בְּעָרֵי הַפְּרָזוֹת, עֹשִׂים אֵת יוֹם אַרְבָּעָה עָשָׂר לְחֹדֶשׁ אֲדָר שִׂמְחָה וּמִשְׁתֶּה וְיוֹם טוֹב, וּמִשְׁלוֹחַ מָנוֹת אִישׁ לְרֵעֵהוּ: וַיִּכְתֹּב מָרְדֳּכַי אֶת הַדְּבָרִים הָאֵלֶּה, וַיִּשְׁלַח סְפָרִים אֶל כָּל הַיְּהוּדִים אֲשֶׁר בְּכָל מְדִינוֹת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ הַקְּרוֹבִים וְהָרְחוֹקִים: לְקַיֵּם עֲלֵיהֶם, לִהְיוֹת עֹשִׂים אֵת יוֹם אַרְבָּעָה עָשָׂר לְחֹדֶשׁ אֲדָר וְאֵת יוֹם חֲמִשָּׁה עָשָׂר בּוֹ, בְּכָל שָׁנָה וְשָׁנָה: כַּיָּמִים אֲשֶׁר נָחוּ בָהֶם הַיְּהוּדִים מֵאוֹיְבֵיהֶם, וְהַחֹדֶשׁ אֲשֶׁר נֶהְפַּךְ לָהֶם מִיָּגוֹן לְשִׂמְחָה וּמֵאֵבֶל לְיוֹם טוֹב, לַעֲשׂוֹת אוֹתָם יְמֵי מִשְׁתֶּה וְשִׂמְחָה וּמִשְׁלוֹחַ מָנוֹת אִישׁ לְרֵעֵהוּ וּמַתָּנוֹת לָאֶבְיוֹנִים: וְקִבֵּל הַיְּהוּדִים אֵת אֲשֶׁר הֵחֵלּוּ לַעֲשׂוֹת, וְאֵת אֲשֶׁר כָּתַב מָרְדֳּכַי אֲלֵיהֶם: כִּי הָמָן בֶּן הַמְּדָתָא הָאֲגָגִי צֹרֵר כָּל הַיְּהוּדִים חָשַׁב עַל הַיְּהוּדִים לְאַבְּדָם, וְהִפִּיל פּוּר הוּא הַגּוֹרָל לְהֻמָּם וּלְאַבְּדָם: וּבְבֹאָהּ לִפְנֵי הַמֶּלֶךְ, אָמַר עִם הַסֵּפֶר יָשׁוּב מַחֲשַׁבְתּוֹ הָרָעָה אֲשֶׁר חָשַׁב עַל הַיְּהוּדִים עַל רֹאשׁוֹ, וְתָלוּ אֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ: עַל כֵּן קָרְאוּ לַיָּמִים הָאֵלֶּה פוּרִים עַל שֵׁם הַפּוּר, עַל כֵּן עַל כָּל דִּבְרֵי הָאִגֶּרֶת הַזֹּאת, וּמָה רָאוּ עַל כָּכָה וּמָה הִגִּיעַ אֲלֵיהֶם: קִיְּמוּ וְקִבְּלוּ הַיְּהוּדִים עֲלֵיהֶם וְעַל זַרְעָם וְעַל כָּל הַנִּלְוִים עֲלֵיהֶם וְלֹא יַעֲבוֹר, לִהְיוֹת עֹשִׂים אֵת שְׁנֵי הַיָּמִים הָאֵלֶּה כִּכְתָבָם וְכִזְמַנָּם, בְּכָל שָׁנָה וְשָׁנָה: וְהַיָּמִים הָאֵלֶּה נִזְכָּרִים וְנַעֲשִׂים בְּכָל דּוֹר וָדוֹר מִשְׁפָּחָה וּמִשְׁפָּחָה מְדִינָה וּמְדִינָה וְעִיר וָעִיר, וִימֵי הַפּוּרִים הָאֵלֶּה לֹא יַעַבְרוּ מִתּוֹךְ הַיְּהוּדִים וְזִכְרָם לֹא יָסוּף מִזַּרְעָם: וַתִּכְתֹּב אֶסְתֵּר הַמַּלְכָּה בַת אֲבִיחַיִל וּמָרְדֳּכַי הַיְּהוּדִי אֶת כָּל תֹּקֶף, לְקַיֵּם אֵת אִגֶּרֶת הַפּוּרִים הַזֹּאת הַשֵּׁנִית: וַיִּשְׁלַח סְפָרִים אֶל כָּל הַיְּהוּדִים, אֶל שֶׁבַע וְעֶשְׂרִים וּמֵאָה מְדִינָה מַלְכוּת אֲחַשְׁוֵרוֹשׁ, דִּבְרֵי שָׁלוֹם וֶאֱמֶת: לְקַיֵּם אֵת יְמֵי הַפֻּרִים הָאֵלֶּה בִּזְמַנֵּיהֶם כַּאֲשֶׁר קִיַּם עֲלֵיהֶם מָרְדֳּכַי הַיְּהוּדִי וְאֶסְתֵּר הַמַּלְכָּה וְכַאֲשֶׁר קִיְּמוּ עַל נַפְשָׁם וְעַל זַרְעָם, דִּבְרֵי הַצֹּמוֹת וְזַעֲקָתָם: וּמַאֲמַר אֶסְתֵּר קִיַּם דִּבְרֵי הַפֻּרִים הָאֵלֶּה, וְנִכְתָּב בַּסֵּפֶר:","cond":["megilatEster"]},{"kind":"header","text":"פרק י'","cond":["megilatEster"]},{"kind":"instruction","text":"פרק י'","cond":["megilatEster"]},{"kind":"text","text":"וַיָּשֶׂם הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ מַס עַל הָאָרֶץ וְאִיֵּי הַיָּם: וְכָל מַעֲשֵׂה תָקְפּוֹ וּגְבוּרָתוֹ, וּפָרָשַׁת גְּדֻלַּת מָרְדֳּכַי אֲשֶׁר גִּדְּלוֹ הַמֶּלֶךְ, הֲלוֹא הֵם כְּתוּבִים עַל סֵפֶר דִּבְרֵי הַיָּמִים לְמַלְכֵי מָדַי וּפָרָס:","cond":["megilatEster"]},{"kind":"special","text":"כִּי מָרְדֳּכַי הַיְּהוּדִי מִשְׁנֶה לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ וְגָדוֹל לַיְּהוּדִים וְרָצוּי לְרֹב אֶחָיו, דֹּרֵשׁ טוֹב לְעַמּוֹ וְדֹבֵר שָׁלוֹם לְכָל זַרְעוֹ:","cond":["megilatEster"]},{"kind":"header","text":"ברכת הרב את ריבנו","cond":["megilatEster"]},{"kind":"instruction","text":"ברכת הרב את ריבנו מברכים גם ביום וגם בלילה, ומברכים אותה רק בציבור של עשרה. ברכה זו מברך רק החזן הקורא את המגילה לאחר שכרך את כל המגילה.","cond":["megilatEster"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הָרָב אֶת רִיבֵנוּ, וְהַדָּן אֶת דִּינֵנוּ, וְהַנּוֹקֵם אֶת נִקְמָתֵנוּ, וְהַמְשַׁלֵּם גְּמוּל לְכָל אוֹיְבֵי נַפְשֵׁנוּ, וְהַנִּפְרָע לָנוּ מִצָּרֵינוּ. בָּרוּךְ אַתָּה יהוה, הַנִּפְרָע לְעַמּוֹ יִשְׂרָאֵל מִכָּל צָרֵיהֶם, הָאֵל הַמּוֹשִׁיעַ.\n\nבָּרוּךְ יהוה אֱלֹהֵי יִשְׂרָאֵל. אָרוּר הָמָן. בָּרוּךְ מָרְדֳּכִי. אֲרוּרָה זֶרֶשׁ וּוַשְׁתִּי. בְּרוּכָה אֶסְתֵּר. אֲרוּרִים עוֹבְדֵי אֱלִילִים. בְּרוּכִים כָּל יִשְׂרָאֵל. וְגַם חַרְבוֹנָה זָכוּר לְטוֹב.","cond":["megilatEster"]},{"kind":"header","text":"ואתה קדוש","cond":["megilatEster"]},{"kind":"text","text":"וְאַתָּה קָדוֹשׁ יוֹשֵׁב תְּהִלּוֹת יִשְׂרָאֵל: וְקָרָא זֶה אֶל זֶה וְאָמַר: קָדוֹשׁ, קָדוֹשׁ, קָדוֹשׁ יהוה צְבָאוֹת, מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ: וּמְקַבְּלִין דֵּין מִן דֵּין וְאָמְרִין: קַדִּישׁ בִּשְׁמֵי מֵרוֹמַא עִלָאַה בֵּית שְׁכִינְתֵּהּ, קַדִּישׁ עַל אַרְעָא עוֹבַד גְּבוּרְתֵּהּ, קַדִּישׁ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא, יהוה צְבָאוֹת מַלְיָא כָל אַרְעָא זִיו יְקָרֵהּ. וַתִּשָּׂאֵנִי רוּחַ, וָאֶשְׁמַע אַחֲרַי קוֹל רַעַשׁ גָּדוֹל: בָּרוּךְ כְּבוֹד יהוה מִמְּקוֹמוֹ: וּנְטָלַתְנִי רוּחָא, וּשְׁמָעִית בַּתְרַי קַל זִיעַ שַׂגִּיא דִמְשַׁבְּחִין וְאָמְרִין: בְּרִיךְ יְקָרָא דַיהוה מֵאֲתָר בֵּית שְׁכִינְתֵּהּ. יהוה יִמְלֹךְ לְעוֹלָם וָעֶד: יהוה מַלְכוּתֵיהּ קָאֵים לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיהוה אֱלֹהֵי אַבְרָהָם יִצְחָק וְיִשְׂרָאֵל אֲבוֹתֵינוּ, שָׁמְרָה זֹּאת לְעוֹלָם, לְיֵצֶר מַחְשְׁבוֹת לְבַב עַמֶּךָ, וְהָכֵן לְבָבָם אֵלֶיךָ: וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית, וְהִרְבָּה לְהָשִׁיב אַפּוֹ, וְלֹא יָעִיר כָּל חֲמָתוֹ: כִּי אַתָּה יהוה טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ: צִדְקָתְךָ צֶּדֶק לְעוֹלָם, וְתוֹרָתְךָ אֱמֶת: תִּתֵּן אֱמֶת לְיַעֲקֹב, חֶסֶד לְאַבְרָהָם, אֲשֶׁר נִשְׁבַּעְתָּ לַאֲבֹתֵינוּ מִימֵי קֶדֶם: בָּרוּךְ אֲדֹנָי יוֹם יוֹם, יַעֲמָס לָנוּ הָאֵל יְשׁוּעָתֵנוּ, סֶלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב, סֶלָה: יהוה צְבָאוֹת אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":["megilatEster"]},{"kind":"instruction","text":"יכוין למסור נפשו על קדושת שמו יתברך כשאומר זה:","cond":["megilatEster"]},{"kind":"text","text":"בָּרוּךְ אֱלֹהֵינוּ שֶׁבְּרָאָנוּ לִכְבוֹדוֹ, וְהִבְדִּילָנוּ מִן הַתּוֹעִים, וְנָתַן לָנוּ תּוֹרַת אֱמֶת, וְחַיֵּי עוֹלָם נָטַע בְּתוֹכֵנוּ. הוּא יִפְתַּח לִבֵּנוּ בְּתוֹרָתוֹ, וְיָשִׂים בְּלִבֵּנוּ אַהֲבָתוֹ וְיִרְאָתוֹ לַעֲשׂוֹת רְצוֹנוֹ וּלְעָבְדוֹ בְּלֵבָב שָׁלֵם. לְמַעַן לֹא נִיגַע לָרִיק, וְלֹא נֵלֵד לַבֶּהָלָה. יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁנִּשְׁמֹר חֻקֶּיךָ וּמִצְוׂתֶיךָ בָּעוֹלָם הַזֶּה, וְנִזְכֶּה וְנִחְיֶה וְנִירַשׁ טוֹבָה וּבְרָכָה לְחַיֵּי הָעוֹלָם הַבָּא. לְמַעַן יְזַמֶּרְךָ כָבוֹד וְלֹא יִדֹּם, יהוה אֱלֹהַי לְעוֹלָם אוֹדֶךָּ: יהוה חָפֵץ לְמַעַן צִדְקוֹ, יַגְדִּיל תּורָה וְיַאְדִּיר: וְיִבְטְחוּ בְךָ יוֹדְעֵי שְׁמֶךָ, כִּי לֹא עָזַבְתָּ דֹּרְשֶׁיךָ יהוה: יהוה אֲדֹנֵינוּ, מָה אַדִּיר שִׁמְךָ בְּכָל הָאָרֶץ: חִזְקוּ וְיַאֲמֵץ לְבַבְכֶם כָּל הַמְיַחֲלִים לַיהוה:","cond":["megilatEster"]},{"kind":"instruction","text":"מברך לאור הנר:","cond":["tishaaBeavFire"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא מְאוֹרֵי הָאֵשׁ.","cond":["tishaaBeavFire"]},{"kind":"header","text":"ואתה קדוש","cond":["tishaaBeav"]},{"kind":"text","text":"וְאַתָּה קָדוֹשׁ יוֹשֵׁב תְּהִלּוֹת יִשְׂרָאֵל: וְקָרָא זֶה אֶל זֶה וְאָמַר: קָדוֹשׁ, קָדוֹשׁ, קָדוֹשׁ יהוה צְבָאוֹת, מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ: וּמְקַבְּלִין דֵּין מִן דֵּין וְאָמְרִין: קַדִּישׁ בִּשְׁמֵי מֵרוֹמַא עִלָאַה בֵּית שְׁכִינְתֵּהּ, קַדִּישׁ עַל אַרְעָא עוֹבַד גְּבוּרְתֵּהּ, קַדִּישׁ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא, יהוה צְבָאוֹת מַלְיָא כָל אַרְעָא זִיו יְקָרֵהּ. וַתִּשָּׂאֵנִי רוּחַ, וָאֶשְׁמַע אַחֲרַי קוֹל רַעַשׁ גָּדוֹל: בָּרוּךְ כְּבוֹד יהוה מִמְּקוֹמוֹ: וּנְטָלַתְנִי רוּחָא, וּשְׁמָעִית בַּתְרַי קַל זִיעַ שַׂגִּיא דִמְשַׁבְּחִין וְאָמְרִין: בְּרִיךְ יְקָרָא דַיהוה מֵאֲתָר בֵּית שְׁכִינְתֵּהּ. יהוה יִמְלֹךְ לְעוֹלָם וָעֶד: יהוה מַלְכוּתֵיהּ קָאֵים לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיהוה אֱלֹהֵי אַבְרָהָם יִצְחָק וְיִשְׂרָאֵל אֲבוֹתֵינוּ, שָׁמְרָה זֹּאת לְעוֹלָם, לְיֵצֶר מַחְשְׁבוֹת לְבַב עַמֶּךָ, וְהָכֵן לְבָבָם אֵלֶיךָ: וְהוּא רַחוּם יְכַפֵּר עָוׂן וְלֹא יַשְׁחִית, וְהִרְבָּה לְהָשִׁיב אַפּוֹ, וְלֹא יָעִיר כָּל חֲמָתוֹ: כִּי אַתָּה יהוה טוֹב וְסַלָּח וְרַב חֶסֶד לְכָל קֹרְאֶיךָ: צִדְקָתְךָ צֶּדֶק לְעוֹלָם, וְתוֹרָתְךָ אֱמֶת: תִּתֵּן אֱמֶת לְיַעֲקֹב, חֶסֶד לְאַבְרָהָם, אֲשֶׁר נִשְׁבַּעְתָּ לַאֲבֹתֵינוּ מִימֵי קֶדֶם: בָּרוּךְ אֲדֹנָי יוֹם יוֹם, יַעֲמָס לָנוּ הָאֵל יְשׁוּעָתֵנוּ, סֶלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב, סֶלָה: יהוה צְבָאוֹת אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":["tishaaBeav"]},{"kind":"instruction","text":"יכוין למסור נפשו על קדושת שמו יתברך כשאומר זה:","cond":["tishaaBeav"]},{"kind":"text","text":"בָּרוּךְ אֱלֹהֵינוּ שֶׁבְּרָאָנוּ לִכְבוֹדוֹ, וְהִבְדִּילָנוּ מִן הַתּוֹעִים, וְנָתַן לָנוּ תּוֹרַת אֱמֶת, וְחַיֵּי עוֹלָם נָטַע בְּתוֹכֵנוּ. הוּא יִפְתַּח לִבֵּנוּ בְּתוֹרָתוֹ, וְיָשִׂים בְּלִבֵּנוּ אַהֲבָתוֹ וְיִרְאָתוֹ לַעֲשׂוֹת רְצוֹנוֹ וּלְעָבְדוֹ בְּלֵבָב שָׁלֵם. לְמַעַן לֹא נִיגַע לָרִיק, וְלֹא נֵלֵד לַבֶּהָלָה. יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁנִּשְׁמֹר חֻקֶּיךָ וּמִצְוׂתֶיךָ בָּעוֹלָם הַזֶּה, וְנִזְכֶּה וְנִחְיֶה וְנִירַשׁ טוֹבָה וּבְרָכָה לְחַיֵּי הָעוֹלָם הַבָּא. לְמַעַן יְזַמֶּרְךָ כָבוֹד וְלֹא יִדֹּם, יהוה אֱלֹהַי לְעוֹלָם אוֹדֶךָּ: יהוה חָפֵץ לְמַעַן צִדְקוֹ, יַגְדִּיל תּורָה וְיַאְדִּיר: וְיִבְטְחוּ בְךָ יוֹדְעֵי שְׁמֶךָ, כִּי לֹא עָזַבְתָּ דֹּרְשֶׁיךָ יהוה: יהוה אֲדֹנֵינוּ, מָה אַדִּיר שִׁמְךָ בְּכָל הָאָרֶץ: חִזְקוּ וְיַאֲמֵץ לְבַבְכֶם כָּל הַמְיַחֲלִים לַיהוה:","cond":["tishaaBeav"]},{"kind":"instruction","text":"קדיש שלם (ללא תתקבל)","cond":["megilatEster"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא, חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה וְשֵיזָבָא וּרְפוּאָה וּגְאֻלָּה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה, לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["megilatEster"]},{"kind":"text","text":"עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["megilatEster"]},{"kind":"instruction","text":"קדיש שלם (ללא תתקבל)","cond":["tishaaBeav"]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא, חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה וְשֵיזָבָא וּרְפוּאָה וּגְאֻלָּה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה, לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav"]},{"kind":"text","text":"עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["tishaaBeav"]},{"kind":"header","text":"שיר למעלות","cond":[]},{"kind":"text","text":"שִׁיר לַמַּעֲלוֹת, אֶשָּׂא עֵינַי אֶל הֶהָרִים, מֵאַיִן יָבֹא עֶזְרִי: עֶזְרִי מֵעִם יהוה, עֹשֵׂה שָׁמַיִם וָאָרֶץ: אַל יִתֵּן לַמּוֹט רַגְלֶךָ, אַל יָנוּם שֹׁמְרֶךָ: הִנֵּה לֹא יָנוּם וְלֹא יִישָׁן שׁוֹמֵר יִשְׂרָאֵל: יהוה שֹׁמְרֶךָ, יהוה צִלְּךָ עַל יַד יְמִינֶךָ: יוֹמָם הַשֶּׁמֶשׁ לֹא יַכֶּכָּה, וְיָרֵחַ בַּלָּיְלָה: יהוה יִשְׁמָרְךָ מִכָּל רָע, יִשְׁמֹר אֶת נַפְשֶׁךָ: יהוה יִשְׁמָר צֵאתְךָ וּבוֹאֶךָ, מֵעַתָּה וְעַד עוֹלָם:","cond":[]},{"kind":"instruction","text":"קדיש יהא שלמא","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא, חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה וְשֵיזָבָא וּרְפוּאָה וּגְאֻלָּה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה, לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"instruction","text":"חזן:","cond":[]},{"kind":"text","text":"בָּרְכוּ אֶת יהוה הַמְבֹרָךְ.","cond":[]},{"kind":"instruction","text":"קהל וחזן:","cond":[]},{"kind":"text","text":"בָּרוּךְ יהוה הַמְבֹרָךְ לְעוֹלָם וָעֶד.","cond":[]},{"kind":"header","text":"עלינו לשבח","cond":[]},{"kind":"text","text":"עָלֵינוּ לְשַׁבֵּחַ לַאֲדוֹן הַכֹּל, לָתֵת גְּדֻלָּה לְיוֹצֵר בְּרֵאשִׁית, שֶׁלֹּא עָשָׂנוּ כְּגוֹיֵי הָאֲרָצוֹת וְלֹא שָׂמָנוּ כְּמִשְׁפְּחוֹת הָאֲדָמָה, שֶׁלֹּא שָׂם חֶלְקֵנוּ כָּהֶם וְגוֹרָלֵנוּ כְּכָל הֲמוֹנָם, שֶׁהֵם מִשְׁתַּחֲוִים לָהֶבֶל וָרִיק וּמִתְפַּלְּלִים אֶל אֵל לֹא יוֹשִׁיעַ, וַאֲנַחְנוּ מִשְׁתַּחֲוִים לִפְנֵי מֶלֶךְ מַלְכֵי הַמְּלָכִים הַקָּדוֹשׁ בָּרוּךְ הוּא, שֶׁהוּא נוֹטֶה שָׁמַיִם וְיוֹסֵד אָרֶץ, וּמוֹשַׁב יְקָרוֹ בַּשָּׁמַיִם מִמַּעַל, וּשְׁכִינַת עֻזּוֹ בְּגָבְהֵי מְרוֹמִים. הוּא אֱלֹהֵינוּ וְאֵין עוֹד אַחֵר. אֱמֶת מַלְכֵּנוּ וְאֶפֶס זוּלָתוֹ, כַּכָּתוּב בַּתּוֹרָה: וְיָדַעְתָּ הַיּוֹם וַהֲשֵׁבוֹתָ אֶל לְבָבֶךָ כִּי יהוה הוּא הָאֱלֹהִים בַּשָּׁמַיִם מִמַּעַל וְעַל הָאָרֶץ מִתָּחַת, אֵין עוֹד:","cond":[]},{"kind":"text","text":"עַל כֵּן נְקַוֶּה לָךְ יהוה אֱלֹהֵינוּ לִרְאוֹת מְהֵרָה בְּתִפְאֶרֶת עֻזָּךְ לְהַעֲבִיר גִּלּוּלִים מִן הָאָרֶץ וְהָאֱלִילִים כָּרוֹת יִכָּרֵתוּן, לְתַקֵּן עוֹלָם בְּמַלְכוּת שַׁדַּי, וְכָל בְּנֵי בָשָׂר יִקְרְאוּ בִשְׁמֶךָ לְהַפְנוֹת אֵלֶיךָ כָּל רִשְׁעֵי אָרֶץ. יַכִּירוּ וְיֵדְעוּ כָּל יוֹשְׁבֵי תֵבֵל כִּי לְךָ תִכְרַע כָּל בֶּרֶךְ, תִּשָּׁבַע כָּל לָשׁוֹן. לְפָנֶיךָ יהוה אֱלֹהֵינוּ יִכְרְעוּ וְיִפֹּלוּ וְלִכְבוֹד שִׁמְךָ יְקָר יִתֵּנוּ, וִיקַבְּלוּ כֻלָּם אֶת עוֹל מַלְכוּתֶךָ, וְתִמְלוֹךְ עֲלֵיהֶם מְהֵרָה לְעוֹלָם וָעֶד. כִּי הַמַּלְכוּת שֶׁלְּךָ הִיא, וּלְעוֹלְמֵי עַד תִּמְלוֹךְ בְּכָבוד, כַּכָּתוּב בְּתוֹרָתָךְ: יהוה יִמְלֹךְ לְעֹלָם וָעֶד: וְנֶאֱמַר: וְהָיָה יהוה לְמֶלֶךְ עַל כָּל הָאָרֶץ, בַּיּום הַהוּא יִהְיֶה יהוה אֶחָד וּשְׁמוֹ אֶחָד:","cond":[]},{"kind":"header","text":"ספירת העומר","cond":["omer"]},{"kind":"instruction","text":"ספירת העומר","cond":["omer"]},{"kind":"text","text":"לְשֵׁם יִחוּד קֻדְשָׁא בְרִיךְ הוּא וּשְׁכִינְתֵּהּ, בִּדְחִילוּ וּרְחִימוּ וּרְחִימוּ וּדְחִילוּ, לְיַחֲדָא שֵׁם אוֹת י' וְאוֹת ה' בְּשֵׁם אוֹת ו' וְאוֹת ה' בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל יִשְׂרָאֵל, לַאֲקָמָא שְׁכִינְתָּא מִעַפְרָא וּלְעִלּוּי שְׁכִינַת עֻזֵּנוּ, הִנֵּה אֲנַחְנוּ בָּאִים לְקַיֵּם מִצְוַת סְפִירַת הָעֹמֶר, כְּדִכְתִיב: וּסְפַרְתֶּם לָכֶם מִמָּחֳרַת הַשַּׁבָּת, מִיּוֹם הֲבִיאֲכֶם אֶת-עֹמֶר הַתְּנוּפָה, שֶׁבַע שַׁבָּתוֹת תְּמִימֹת תִּהְיֶינָה: עַד מִמָּחֳרַת הַשַּׁבָּת הַשְּׁבִיעִת, תִּסְפְּרוּ חֲמִשִּׁים יוֹם, וְהִקְרַבְתֶּם מִנְחָה חֲדָשָׁה, לַיהוָה: לְתַקֵּן אֶת שָׁרְשָׁהּ בְּמָקוֹם עֶלְיוֹן, לַעֲשׂוֹת נַחַת רוּחַ לְיוֹצְרֵנוּ וְלַעֲשׂוֹת רְצוֹן בּוֹרְאֵנוּ. וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹננָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ: יהוה יִגְמֹר בַּעֲדִי, יהוה חַסְדּךָ לְעוֹלָם, מַעֲשֵׂי יָדֶיךָ אַל תֶּרֶף: אֶקְרָא לֵאלֹהִים עֶלְיוֹן, לָאֵל גֹּמֵר עָלָי: וְנֶאֱמַר: וָאֶעֱבֹר עָלַיִךְ וָאֶרְאֵךְ מִתְבּוֹסֶסֶת בּדָמָיִךְ, וָאֹמַר לָךְ בְּדָמַיִךְ חֲיִי, וָאֹמַר לָךְ בּדָמַיִךְ חֲיִי: בָּרְכִי נַפְשִׁי אֶת יהוה, יהוה אֱלֹהַי גָּדַלְתָּ מְּאֹד, הוֹד וְהָדָר לָבַשְׁתָּ: עֹטֶה אוֹר כַּשַּׂלְמָה, נֹטֶה שָׁמַיִם כַּיְרִיעָה:\n\nחזן - בִּרְשׁוּת מוֹרַי וְרַבּוֹתַי.\nקהל - שָמַיִם.\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ עַל סְפִירַת הָעֹמֶר.\n\n:::::\n\nהָרַחֲמָן הוּא יִבְנֶה בֵית הַמִּקְדָּש, וְיַחֲזִיר הָעֲבוֹדָה לִמְקוֹמָהּ בִּמְהֵרָה בְיָמֵינוּ. אמן.\n\nלַמְנַצֵּח בִּנְגִינֹת מִזְמוֹר שִׁיר: אֱלֹהִים יְחָנֵּנוּ וִיבָרְכֵנוּ, יָאֵר פָּנָיו אִתָּנוּ סֶלָה: לָדַעַת בָּאָרֶץ דַּרְכֶּךָ, בְּכָל גּוֹיִם יְשׁוּעָתֶךָ: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: יִשְׂמְחוּ וִירַנְּנוּ לְאֻמִּים כִּי תִשְׁפֹּט עַמִּים מִישׁוֹר, וּלְאֻמִּים בָּאָרֶץ תַּנְחֵם סֶלָה: יוֹדוּךָ עַמִּים אֱלֹהִים יוֹדוּךָ עַמִּים כֻּלָּם: אֶרֶץ נָתְנָה יְבוּלָהּ, יְבָרְכֵנוּ אֱלֹהִים אֱלֹהֵינוּ: יְבָרְכֵנוּ אֱלֹהִים, וְיִירְאוּ אֹתוֹ כָּל אַפְסֵי אָרֶץ:","cond":["omer"]},{"kind":"text","text":"אָנָּא, בְּכֹחַ גְּדֻלַּת יְמִינְךָ, תַּתִּיר צְרוּרָה (אב\"ג ית\"ץ).","cond":["omer"]},{"kind":"text","text":"קַבֵּל רִנַּת עַמְּךָ, שַׂגְּבֵנוּ, טַהֲרֵנוּ, נוֹרָא (קר\"ע שט\"ן).","cond":["omer"]},{"kind":"text","text":"נָא גִּבּוֹר, דּוֹרְשֵׁי יִחוּדֶךָ, כְּבָבַת שָׁמְרֵם (נג\"ד יכ\"ש).","cond":["omer"]},{"kind":"text","text":"בָּרְכֵם, טַהֲרֵם, רַחֲמֵי צִדְקָתְךָ תָּמִיד גָּמְלֵם (בט\"ר צת\"ג).","cond":["omer"]},{"kind":"text","text":"חָסִין קָדוֹשׁ, בְּרֹב טוּבְךָ נַהֵל עֲדָתֶךָ (חק\"ב טנ\"ע).","cond":["omer"]},{"kind":"text","text":"יָחִיד גֵּאֶה, לְעַמְּךָ פְנֵה, זוֹכְרֵי קְדֻשָּׁתֶךָ (יג\"ל פז\"ק).","cond":["omer"]},{"kind":"text","text":"שַׁוְעָתֵנוּ קַבֵּל, וּשְׁמַע צַעֲקָתֵנוּ, יוֹדֵעַ תַּעֲלוּמוֹת (שק\"ו צי\"ת).","cond":["omer"]},{"kind":"instruction","text":"בלחש:","cond":["omer"]},{"kind":"text","text":"בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד.","cond":["omer"]},{"kind":"header","text":"אני מאמין","cond":["yerushalayim"]},{"kind":"instruction","text":"שרים:","cond":["yerushalayim"]},{"kind":"text","text":"אֲנִי מַאֲמִין בֶּאֱמוּנָה שְׁלֵמָה בְּבִיאַת הַמָּשִׁיחַ, וְאַף עַל פִּי שֶׁיִּתְמַהְמֵהַּ, עִם כָּל זֶה אֲחַכֶּה לוֹ בְּכָל יוֹם שֶׁיָּבוֹא.","cond":["yerushalayim"]},{"kind":"header","text":"הבדלה","cond":["havdala"]},{"kind":"instruction","text":"סדר הבדלה\n\nנוטל הכוס בידו ואומר:","cond":["havdala"]},{"kind":"text","text":"רִאשׁוֹן לְצִיּוֹן הִנֵּה הִנָּם, וְלִירוּשָׁלַיִם מְבַשֵּׂר אֶתֵּן: אַל תִּשְׂמְחִי אוֹיַבְתִּי לִי כִּי נָפַלְתִּי קַמְתִּי, כִּי אֵשֵׁב בַּחוֹשֶׁךְ יהוה אוֹר לִי: לַיּהוּדִים הָיְתָה אוֹרָה וְשִׂמְחָה, וְשָׂשֹׂן וִיקָר: וַיְהִי דָוִד לְכָל דְּרָכָיו מַשְׂכִּיל וַיהוה עִמּוֹ: וְנֹחַ מָצָא חֵן בְּעֵינֵי יהוה: כֵּן נִמְצָא חֵן וְשֵׂכֶל טוֹב בְּעֵינֵי אֱלֹהִים וְאָדָם.\n\nקוּמִי אוֹרִי כִּי בָא אוֹרֵךְ, וּכְבוֹד יהוה עָלַיִךְ זָרַח: כִּי הִנֵּה הַחֹשֶׁךְ יְכַסֶּה אֶרֶץ וַעֲרָפֶל לְאֻמִּים, וְעָלַיִךְ יִזְרַח יהוה וּכְבוֹדוֹ עָלַיִךְ יֵרָאֶה:","cond":["havdala"]},{"kind":"instruction","text":"יקח הכוס בידו ויאמר:","cond":["havdala"]},{"kind":"text","text":"כּוֹס ישׁוּעוֹת אֶשָּׂא, וּבְשֵׁם יהוה אֶקְרָא:\nאָנָּא יהוה הוֹשִׁיעָה נָּא,\nאָנָּא יהוה הוֹשִׁיעָה נָּא,\nאָנָּא יהוה הַצְלִיחָה נָא:\nאָנָּא יהוה הַצְלִיחָה נָא:\n\nהַצְלִיחֵנוּ, הַצְלַח דּרָכֵינוּ, הַצְלַח לִמּוּדֵינוּ, וּשְׁלַח בְּרָכָה רְוָחָה וְהַצְלָחָה בְּכָל מַעֲשֵׂה יָדֵינוּ, כְּדִכְתִיב: יִשָּׂא בְרָכָה מֵאֵת יהוה וּצְדָקָה מֵאֱלֹהֵי יִשְׁעוֹ: לַיּהוּדִים הָיְתָה אוֹרָה וְשִׂמְחָה, וְשָׂשֹׂן וִיקָר: וּכְתִיב: וַיְהִי דָוִד לְכָל דְּרָכָיו מַשְׂכִּיל, וַיהוה עִמּוֹ: כֵּן יִהְיֶה עִמָּנוּ תָמִיד.\n\nסַבְרֵי מָרָנָן.","cond":["havdala"]},{"kind":"instruction","text":"ועונים:","cond":["havdala"]},{"kind":"text","text":"לחַיִּים.","cond":["havdala"]},{"kind":"instruction","text":"המבדיל ממשיך:","cond":["havdala"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא פְּרִי הַגֶּפֶן.","cond":["havdala"]},{"kind":"instruction","text":"ואם מברך על משקה שאינו יין יברך שהכל.","cond":["havdala"]},{"kind":"instruction","text":"מוריד את הכוס ונוטל את הבשמים ומברך:","cond":["havdala","sun"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא (עֲצֵי או עִשְׂבֵּי או מִינֵי) בְשָׂמִים.","cond":["havdala","sun"]},{"kind":"instruction","text":"מברך לאור הנר:","cond":["havdala","fire"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא מְאוֹרֵי הָאֵשׁ.","cond":["havdala","fire"]},{"kind":"instruction","text":"נוטל את הכוס בידו ומברך:","cond":["havdala"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַמַּבְדִּיל בֵּין קֹדֶשׁ לְחוֹל וּבֵין אוֹר לְחֹשֶׁךְ וּבֵין יִשְׂרָאֵל לָעַמִּים וּבֵין יוֹם הַשְּׁבִיעִי לְשֵׁשֶׁת יְמֵי הַמַּעֲשֶׂה. בָּרוּךְ אַתָּה יהוה, הַמַּבְדִּיל בֵּין קֹדֶשׁ לְחוֹל.","cond":["havdala"]},{"kind":"instruction","text":"אם שתה רביעית יין יברך ברכת מעין שלש (מופיע בתפריט התפילות).","cond":["havdala"]}]}};
